const FULL_QURAN=[{"s":1,"a":1,"key":"1:1","ar":"بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ","en":"In the name of Allāh,1 the Entirely Merciful, the Especially Merciful.2","tr":"Bismi Allahi arrahmani arraheem","juz":1,"page":1},{"s":1,"a":2,"key":"1:2","ar":"ٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَـٰلَمِينَ","en":"[All] praise is [due] to Allāh, Lord1 of the worlds -","tr":"Alhamdu lillahi rabbi alAAalameen","juz":1,"page":1},{"s":1,"a":3,"key":"1:3","ar":"ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ","en":"The Entirely Merciful, the Especially Merciful,","tr":"Arrahmani arraheem","juz":1,"page":1},{"s":1,"a":4,"key":"1:4","ar":"مَـٰلِكِ يَوْمِ ٱلدِّينِ","en":"Sovereign of the Day of Recompense.1","tr":"Maliki yawmi addeen","juz":1,"page":1},{"s":1,"a":5,"key":"1:5","ar":"إِيَّاكَ نَعْبُدُ وَإِيَّاكَ نَسْتَعِينُ","en":"It is You we worship and You we ask for help.","tr":"Iyyaka naAAbudu wa-iyyaka nastaAAeen","juz":1,"page":1},{"s":1,"a":6,"key":"1:6","ar":"ٱهْدِنَا ٱلصِّرَٰطَ ٱلْمُسْتَقِيمَ","en":"Guide us to the straight path -","tr":"Ihdina assirata almustaqeem","juz":1,"page":1},{"s":1,"a":7,"key":"1:7","ar":"صِرَٰطَ ٱلَّذِينَ أَنْعَمْتَ عَلَيْهِمْ غَيْرِ ٱلْمَغْضُوبِ عَلَيْهِمْ وَلَا ٱلضَّآلِّينَ","en":"The path of those upon whom You have bestowed favor, not of those who have earned [Your] anger or of those who are astray.","tr":"Sirata allatheena anAAamta AAalayhim ghayri almaghdoobi AAalayhim wala addalleen","juz":1,"page":1},{"s":2,"a":1,"key":"2:1","ar":" الٓمٓ","en":"Alif, Lām, Meem.1","tr":"Alif-lam-meem","juz":1,"page":2},{"s":2,"a":2,"key":"2:2","ar":"ذَٰلِكَ ٱلْكِتَـٰبُ لَا رَيْبَ ۛ فِيهِ ۛ هُدًى لِّلْمُتَّقِينَ","en":"This is the Book about which there is no doubt, a guidance for those conscious of Allāh1 -","tr":"Thalika alkitabu larayba feehi hudan lilmuttaqeen","juz":1,"page":2},{"s":2,"a":3,"key":"2:3","ar":"ٱلَّذِينَ يُؤْمِنُونَ بِٱلْغَيْبِ وَيُقِيمُونَ ٱلصَّلَوٰةَ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَ","en":"Who believe in the unseen, establish prayer,1 and spend out of what We2 have provided for them,","tr":"Allatheena yu/minoona bilghaybiwayuqeemoona assalata wamimma razaqnahumyunfiqoon","juz":1,"page":2},{"s":2,"a":4,"key":"2:4","ar":"وَٱلَّذِينَ يُؤْمِنُونَ بِمَآ أُنزِلَ إِلَيْكَ وَمَآ أُنزِلَ مِن قَبْلِكَ وَبِٱلْـَٔاخِرَةِ هُمْ يُوقِنُونَ","en":"And who believe in what has been revealed to you, [O Muḥammad], and what was revealed before you, and of the Hereafter they are certain [in faith].","tr":"Wallatheena yu/minoona bimaonzila ilayka wama onzila min qablika wabil-akhiratihum yooqinoon","juz":1,"page":2},{"s":2,"a":5,"key":"2:5","ar":"أُو۟لَـٰٓئِكَ عَلَىٰ هُدًى مِّن رَّبِّهِمْ ۖ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"Those are upon [right] guidance from their Lord, and it is those who are the successful.","tr":"Ola-ika AAala hudan minrabbihim waola-ika humu almuflihoon","juz":1,"page":2},{"s":2,"a":6,"key":"2:6","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ سَوَآءٌ عَلَيْهِمْ ءَأَنذَرْتَهُمْ أَمْ لَمْ تُنذِرْهُمْ لَا يُؤْمِنُونَ","en":"Indeed, those who disbelieve1 - it is all the same for them whether you warn them or do not warn them - they will not believe.","tr":"Inna allatheena kafaroo sawaonAAalayhim aanthartahum am lam tunthirhum layu/minoon","juz":1,"page":3},{"s":2,"a":7,"key":"2:7","ar":"خَتَمَ ٱللَّهُ عَلَىٰ قُلُوبِهِمْ وَعَلَىٰ سَمْعِهِمْ ۖ وَعَلَىٰٓ أَبْصَـٰرِهِمْ غِشَـٰوَةٌ ۖ وَلَهُمْ عَذَابٌ عَظِيمٌ","en":"Allāh has set a seal upon their hearts and upon their hearing, and over their vision is a veil.1 And for them is a great punishment.","tr":"Khatama Allahu AAala quloobihimwaAAala samAAihim waAAala absarihim ghishawatunwalahum AAathabun AAatheem","juz":1,"page":3},{"s":2,"a":8,"key":"2:8","ar":"وَمِنَ ٱلنَّاسِ مَن يَقُولُ ءَامَنَّا بِٱللَّهِ وَبِٱلْيَوْمِ ٱلْـَٔاخِرِ وَمَا هُم بِمُؤْمِنِينَ","en":"And of the people are some who say, \"We believe in Allāh and the Last Day,\" but they are not believers.","tr":"Wamina annasi man yaqoolu amannabiAllahi wabilyawmi al-akhiri wamahum bimu/mineen","juz":1,"page":3},{"s":2,"a":9,"key":"2:9","ar":"يُخَـٰدِعُونَ ٱللَّهَ وَٱلَّذِينَ ءَامَنُوا۟ وَمَا يَخْدَعُونَ إِلَّآ أَنفُسَهُمْ وَمَا يَشْعُرُونَ","en":"They [think to] deceive Allāh and those who believe, but they deceive not except themselves and perceive [it] not.","tr":"YukhadiAAoona Allaha wallatheenaamanoo wama yakhdaAAoona illa anfusahum wamayashAAuroon","juz":1,"page":3},{"s":2,"a":10,"key":"2:10","ar":"فِى قُلُوبِهِم مَّرَضٌ فَزَادَهُمُ ٱللَّهُ مَرَضًا ۖ وَلَهُمْ عَذَابٌ أَلِيمٌۢ بِمَا كَانُوا۟ يَكْذِبُونَ","en":"In their hearts is disease, so Allāh has increased their disease;1 and for them is a painful punishment because they [habitually] used to lie.","tr":"Fee quloobihim maradun fazadahumuAllahu maradan walahum AAathabun aleemun bimakanoo yakthiboon","juz":1,"page":3},{"s":2,"a":11,"key":"2:11","ar":"وَإِذَا قِيلَ لَهُمْ لَا تُفْسِدُوا۟ فِى ٱلْأَرْضِ قَالُوٓا۟ إِنَّمَا نَحْنُ مُصْلِحُونَ","en":"And when it is said to them, \"Do not cause corruption on the earth,\" they say, \"We are but reformers.\"","tr":"Wa-itha qeela lahum latufsidoo fee al-ardi qaloo innama nahnumuslihoon","juz":1,"page":3},{"s":2,"a":12,"key":"2:12","ar":"أَلَآ إِنَّهُمْ هُمُ ٱلْمُفْسِدُونَ وَلَـٰكِن لَّا يَشْعُرُونَ","en":"Unquestionably, it is they who are the corrupters, but they perceive [it] not.","tr":"Ala innahum humu almufsidoona walakinla yashAAuroon","juz":1,"page":3},{"s":2,"a":13,"key":"2:13","ar":"وَإِذَا قِيلَ لَهُمْ ءَامِنُوا۟ كَمَآ ءَامَنَ ٱلنَّاسُ قَالُوٓا۟ أَنُؤْمِنُ كَمَآ ءَامَنَ ٱلسُّفَهَآءُ ۗ أَلَآ إِنَّهُمْ هُمُ ٱلسُّفَهَآءُ وَلَـٰكِن لَّا يَعْلَمُونَ","en":"And when it is said to them, \"Believe as the people have believed,\" they say, \"Should we believe as the foolish have believed?\" Unquestionably, it is they who are the foolish, but they know [it] not.","tr":"Wa-itha qeela lahum aminoo kamaamana annasu qaloo anu/minu kamaamana assufahao ala innahum humu assufahaowalakin la yaAAlamoon","juz":1,"page":3},{"s":2,"a":14,"key":"2:14","ar":"وَإِذَا لَقُوا۟ ٱلَّذِينَ ءَامَنُوا۟ قَالُوٓا۟ ءَامَنَّا وَإِذَا خَلَوْا۟ إِلَىٰ شَيَـٰطِينِهِمْ قَالُوٓا۟ إِنَّا مَعَكُمْ إِنَّمَا نَحْنُ مُسْتَهْزِءُونَ","en":"And when they meet those who believe, they say, \"We believe\"; but when they are alone with their evil ones, they say, \"Indeed, we are with you; we were only mockers.\"","tr":"Wa-itha laqoo allatheena amanooqaloo amanna wa-itha khalaw ilashayateenihim qaloo inna maAAakum innamanahnu mustahzi-oon","juz":1,"page":3},{"s":2,"a":15,"key":"2:15","ar":"ٱللَّهُ يَسْتَهْزِئُ بِهِمْ وَيَمُدُّهُمْ فِى طُغْيَـٰنِهِمْ يَعْمَهُونَ","en":"[But] Allāh mocks them and prolongs them in their transgression [while] they wander blindly.","tr":"Allahu yastahzi-o bihim wayamudduhumfee tughyanihim yaAAmahoon","juz":1,"page":3},{"s":2,"a":16,"key":"2:16","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلضَّلَـٰلَةَ بِٱلْهُدَىٰ فَمَا رَبِحَت تِّجَـٰرَتُهُمْ وَمَا كَانُوا۟ مُهْتَدِينَ","en":"Those are the ones who have purchased error [in exchange] for guidance, so their transaction has brought no profit, nor were they guided.","tr":"Ola-ika allatheena ishtarawooaddalalata bilhuda famarabihat tijaratuhum wama kanoomuhtadeen","juz":1,"page":3},{"s":2,"a":17,"key":"2:17","ar":"مَثَلُهُمْ كَمَثَلِ ٱلَّذِى ٱسْتَوْقَدَ نَارًا فَلَمَّآ أَضَآءَتْ مَا حَوْلَهُۥ ذَهَبَ ٱللَّهُ بِنُورِهِمْ وَتَرَكَهُمْ فِى ظُلُمَـٰتٍ لَّا يُبْصِرُونَ","en":"Their example is that of one who kindled a fire, but when it illuminated what was around him, Allāh took away their light and left them in darkness [so] they could not see.","tr":"Mathaluhum kamathali allatheeistawqada naran falamma adaat ma hawlahuthahaba Allahu binoorihim watarakahum fee thulumatinla yubsiroon","juz":1,"page":4},{"s":2,"a":18,"key":"2:18","ar":"صُمٌّۢ بُكْمٌ عُمْىٌ فَهُمْ لَا يَرْجِعُونَ","en":"Deaf, dumb and blind - so they will not return [to the right path].","tr":"Summun bukmun AAumyun fahum layarjiAAoon","juz":1,"page":4},{"s":2,"a":19,"key":"2:19","ar":"أَوْ كَصَيِّبٍ مِّنَ ٱلسَّمَآءِ فِيهِ ظُلُمَـٰتٌ وَرَعْدٌ وَبَرْقٌ يَجْعَلُونَ أَصَـٰبِعَهُمْ فِىٓ ءَاذَانِهِم مِّنَ ٱلصَّوَٰعِقِ حَذَرَ ٱلْمَوْتِ ۚ وَٱللَّهُ مُحِيطٌۢ بِٱلْكَـٰفِرِينَ","en":"Or [it is] like a rainstorm from the sky within which is darkness, thunder and lightning. They put their fingers in their ears against the thunderclaps in dread of death. But Allāh is encompassing1 of the disbelievers.","tr":"Aw kasayyibin mina assama-ifeehi thulumatun waraAAdun wabarqunyajAAaloona asabiAAahum fee athanihim mina assawaAAiqihathara almawti wallahu muheetunbilkafireen","juz":1,"page":4},{"s":2,"a":20,"key":"2:20","ar":"يَكَادُ ٱلْبَرْقُ يَخْطَفُ أَبْصَـٰرَهُمْ ۖ كُلَّمَآ أَضَآءَ لَهُم مَّشَوْا۟ فِيهِ وَإِذَآ أَظْلَمَ عَلَيْهِمْ قَامُوا۟ ۚ وَلَوْ شَآءَ ٱللَّهُ لَذَهَبَ بِسَمْعِهِمْ وَأَبْصَـٰرِهِمْ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"The lightning almost snatches away their sight. Every time it lights [the way] for them, they walk therein; but when darkness comes over them, they stand [still]. And if Allāh had willed, He could have taken away their hearing and their sight. Indeed, Allāh is over all things competent.","tr":"Yakadu albarqu yakhtafu absarahumkullama adaa lahum mashaw feehi wa-itha athlamaAAalayhim qamoo walaw shaa Allahu lathahababisamAAihim waabsarihim inna Allaha AAalakulli shay-in qadeer","juz":1,"page":4},{"s":2,"a":21,"key":"2:21","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ ٱعْبُدُوا۟ رَبَّكُمُ ٱلَّذِى خَلَقَكُمْ وَٱلَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ","en":"O mankind, worship your Lord, who created you and those before you, that you may become righteous -","tr":"Ya ayyuha annasuoAAbudoo rabbakumu allathee khalaqakum wallatheenamin qablikum laAAallakum tattaqoon","juz":1,"page":4},{"s":2,"a":22,"key":"2:22","ar":"ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ فِرَٰشًا وَٱلسَّمَآءَ بِنَآءً وَأَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً فَأَخْرَجَ بِهِۦ مِنَ ٱلثَّمَرَٰتِ رِزْقًا لَّكُمْ ۖ فَلَا تَجْعَلُوا۟ لِلَّهِ أَندَادًا وَأَنتُمْ تَعْلَمُونَ","en":"[He] who made for you the earth a bed [spread out] and the sky a ceiling and sent down from the sky, rain and brought forth thereby fruits as provision for you. So do not attribute to Allāh equals while you know [that there is nothing similar to Him].","tr":"Allathee jaAAala lakumu al-ardafirashan wassamaa binaan waanzalamina assama-i maan faakhraja bihi mina aththamaratirizqan lakum fala tajAAaloo lillahi andadanwaantum taAAlamoon","juz":1,"page":4},{"s":2,"a":23,"key":"2:23","ar":"وَإِن كُنتُمْ فِى رَيْبٍ مِّمَّا نَزَّلْنَا عَلَىٰ عَبْدِنَا فَأْتُوا۟ بِسُورَةٍ مِّن مِّثْلِهِۦ وَٱدْعُوا۟ شُهَدَآءَكُم مِّن دُونِ ٱللَّهِ إِن كُنتُمْ صَـٰدِقِينَ","en":"And if you are in doubt about what We have sent down [i.e., the Qur’ān] upon Our Servant [i.e., Prophet Muḥammad (ﷺ)], then produce a sūrah the like thereof and call upon your witnesses [i.e., supporters] other than Allāh, if you should be truthful.","tr":"Wa-in kuntum fee raybin mimma nazzalnaAAala AAabdina fa/too bisooratin min mithlihi wadAAooshuhadaakum min dooni Allahi in kuntum sadiqeen","juz":1,"page":4},{"s":2,"a":24,"key":"2:24","ar":"فَإِن لَّمْ تَفْعَلُوا۟ وَلَن تَفْعَلُوا۟ فَٱتَّقُوا۟ ٱلنَّارَ ٱلَّتِى وَقُودُهَا ٱلنَّاسُ وَٱلْحِجَارَةُ ۖ أُعِدَّتْ لِلْكَـٰفِرِينَ","en":"But if you do not - and you will never be able to - then fear the Fire, whose fuel is people and stones, prepared for the disbelievers.","tr":"Fa-in lam tafAAaloo walan tafAAaloo fattaqooannara allatee waqooduha annasuwalhijaratu oAAiddat lilkafireen","juz":1,"page":4},{"s":2,"a":25,"key":"2:25","ar":"وَبَشِّرِ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ أَنَّ لَهُمْ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ۖ كُلَّمَا رُزِقُوا۟ مِنْهَا مِن ثَمَرَةٍ رِّزْقًا ۙ قَالُوا۟ هَـٰذَا ٱلَّذِى رُزِقْنَا مِن قَبْلُ ۖ وَأُتُوا۟ بِهِۦ مُتَشَـٰبِهًا ۖ وَلَهُمْ فِيهَآ أَزْوَٰجٌ مُّطَهَّرَةٌ ۖ وَهُمْ فِيهَا خَـٰلِدُونَ","en":"And give good tidings to those who believe and do righteous deeds that they will have gardens [in Paradise] beneath which rivers flow. Whenever they are provided with a provision of fruit therefrom, they will say, \"This is what we were provided with before.\" And it is given to them in likeness. And they will have therein purified spouses, and they will abide therein eternally.","tr":"Wabashshiri allatheena amanoowaAAamiloo assalihati anna lahum jannatintajree min tahtiha al-anharu kullamaruziqoo minha min thamaratin rizqan qaloo hathaallathee ruziqna min qablu waotoo bihi mutashabihanwalahum feeha azwajun mutahharatun wahumfeeha khalidoon","juz":1,"page":5},{"s":2,"a":26,"key":"2:26","ar":"۞ إِنَّ ٱللَّهَ لَا يَسْتَحْىِۦٓ أَن يَضْرِبَ مَثَلًا مَّا بَعُوضَةً فَمَا فَوْقَهَا ۚ فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ فَيَعْلَمُونَ أَنَّهُ ٱلْحَقُّ مِن رَّبِّهِمْ ۖ وَأَمَّا ٱلَّذِينَ كَفَرُوا۟ فَيَقُولُونَ مَاذَآ أَرَادَ ٱللَّهُ بِهَـٰذَا مَثَلًا ۘ يُضِلُّ بِهِۦ كَثِيرًا وَيَهْدِى بِهِۦ كَثِيرًا ۚ وَمَا يُضِلُّ بِهِۦٓ إِلَّا ٱلْفَـٰسِقِينَ","en":"Indeed, Allāh is not timid to present an example - that of a mosquito or what is smaller1 than it. And those who have believed know that it is the truth from their Lord. But as for those who disbelieve, they say, \"What did Allāh intend by this as an example?\" He misleads many thereby and guides many thereby. And He misleads not except the defiantly disobedient,","tr":"Inna Allaha la yastahyeean yadriba mathalan ma baAAoodatan famafawqaha faamma allatheena amanoofayaAAlamoona annahu alhaqqu min rabbihim waammaallatheena kafaroo fayaqooloona matha aradaAllahu bihatha mathalan yudillu bihikatheeran wayahdee bihi katheeran wama yudillu bihiilla alfasiqeen","juz":1,"page":5},{"s":2,"a":27,"key":"2:27","ar":"ٱلَّذِينَ يَنقُضُونَ عَهْدَ ٱللَّهِ مِنۢ بَعْدِ مِيثَـٰقِهِۦ وَيَقْطَعُونَ مَآ أَمَرَ ٱللَّهُ بِهِۦٓ أَن يُوصَلَ وَيُفْسِدُونَ فِى ٱلْأَرْضِ ۚ أُو۟لَـٰٓئِكَ هُمُ ٱلْخَـٰسِرُونَ","en":"Who break the covenant of Allāh after contracting it and sever that which Allāh has ordered to be joined and cause corruption on earth. It is those who are the losers.","tr":"Allatheena yanqudoona AAahdaAllahi min baAAdi meethaqihi wayaqtaAAoona maamara Allahu bihi an yoosala wayufsidoona fee al-ardiola-ika humu alkhasiroon","juz":1,"page":5},{"s":2,"a":28,"key":"2:28","ar":"كَيْفَ تَكْفُرُونَ بِٱللَّهِ وَكُنتُمْ أَمْوَٰتًا فَأَحْيَـٰكُمْ ۖ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْ ثُمَّ إِلَيْهِ تُرْجَعُونَ","en":"How can you disbelieve in Allāh when you were lifeless and He brought you to life; then He will cause you to die, then He will bring you [back] to life, and then to Him you will be returned.","tr":"Kayfa takfuroona billahiwakuntum amwatan faahyakum thumma yumeetukumthumma yuhyeekum thumma ilayhi turjaAAoon","juz":1,"page":5},{"s":2,"a":29,"key":"2:29","ar":"هُوَ ٱلَّذِى خَلَقَ لَكُم مَّا فِى ٱلْأَرْضِ جَمِيعًا ثُمَّ ٱسْتَوَىٰٓ إِلَى ٱلسَّمَآءِ فَسَوَّىٰهُنَّ سَبْعَ سَمَـٰوَٰتٍ ۚ وَهُوَ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"It is He who created for you all of that which is on the earth. Then He directed Himself1 to the heaven, [His being above all creation], and made them seven heavens, and He is Knowing of all things.","tr":"Huwa allathee khalaqa lakum mafee al-ardi jameeAAan thumma istawa ila assama-ifasawwahunna sabAAa samawatin wahuwa bikullishay-in AAaleem","juz":1,"page":5},{"s":2,"a":30,"key":"2:30","ar":"وَإِذْ قَالَ رَبُّكَ لِلْمَلَـٰٓئِكَةِ إِنِّى جَاعِلٌ فِى ٱلْأَرْضِ خَلِيفَةً ۖ قَالُوٓا۟ أَتَجْعَلُ فِيهَا مَن يُفْسِدُ فِيهَا وَيَسْفِكُ ٱلدِّمَآءَ وَنَحْنُ نُسَبِّحُ بِحَمْدِكَ وَنُقَدِّسُ لَكَ ۖ قَالَ إِنِّىٓ أَعْلَمُ مَا لَا تَعْلَمُونَ","en":"And [mention, O Muḥammad], when your Lord said to the angels, \"Indeed, I will make upon the earth a successive authority.\"1 They said, \"Will You place upon it one who causes corruption therein and sheds blood, while we exalt You with praise and declare Your perfection?\"2 He [Allāh] said, \"Indeed, I know that which you do not know.\"","tr":"Wa-ith qala rabbuka lilmala-ikatiinnee jaAAilun fee al-ardi khaleefatan qalooatajAAalu feeha man yufsidu feeha wayasfiku addimaawanahnu nusabbihu bihamdika wanuqaddisu lakaqala innee aAAlamu ma la taAAlamoon","juz":1,"page":6},{"s":2,"a":31,"key":"2:31","ar":"وَعَلَّمَ ءَادَمَ ٱلْأَسْمَآءَ كُلَّهَا ثُمَّ عَرَضَهُمْ عَلَى ٱلْمَلَـٰٓئِكَةِ فَقَالَ أَنۢبِـُٔونِى بِأَسْمَآءِ هَـٰٓؤُلَآءِ إِن كُنتُمْ صَـٰدِقِينَ","en":"And He taught Adam the names - all of them. Then He showed them to the angels and said, \"Inform Me of the names of these, if you are truthful.\"","tr":"WaAAallama adama al-asmaakullaha thumma AAaradahum AAala almala-ikatifaqala anbi-oonee bi-asma-i haola-iin kuntum sadiqeen","juz":1,"page":6},{"s":2,"a":32,"key":"2:32","ar":"قَالُوا۟ سُبْحَـٰنَكَ لَا عِلْمَ لَنَآ إِلَّا مَا عَلَّمْتَنَآ ۖ إِنَّكَ أَنتَ ٱلْعَلِيمُ ٱلْحَكِيمُ","en":"They said, \"Exalted are You; we have no knowledge except what You have taught us. Indeed, it is You who is the Knowing,1 the Wise.\"2","tr":"Qaloo subhanaka laAAilma lana illa ma AAallamtanainnaka anta alAAaleemu alhakeem","juz":1,"page":6},{"s":2,"a":33,"key":"2:33","ar":"قَالَ يَـٰٓـَٔادَمُ أَنۢبِئْهُم بِأَسْمَآئِهِمْ ۖ فَلَمَّآ أَنۢبَأَهُم بِأَسْمَآئِهِمْ قَالَ أَلَمْ أَقُل لَّكُمْ إِنِّىٓ أَعْلَمُ غَيْبَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَأَعْلَمُ مَا تُبْدُونَ وَمَا كُنتُمْ تَكْتُمُونَ","en":"He said, \"O Adam, inform them of their names.\" And when he had informed them of their names, He said, \"Did I not tell you that I know the unseen [aspects] of the heavens and the earth? And I know what you reveal and what you have concealed.\"","tr":"Qala ya adamu anbi/humbi-asma-ihim falamma anbaahum bi-asma-ihim qalaalam aqul lakum innee aAAlamu ghayba assamawatiwal-ardi waaAAlamu ma tubdoona wamakuntum taktumoon","juz":1,"page":6},{"s":2,"a":34,"key":"2:34","ar":"وَإِذْ قُلْنَا لِلْمَلَـٰٓئِكَةِ ٱسْجُدُوا۟ لِـَٔادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ أَبَىٰ وَٱسْتَكْبَرَ وَكَانَ مِنَ ٱلْكَـٰفِرِينَ","en":"And [mention] when We said to the angels, \"Prostrate before Adam\"; so they prostrated, except for Iblees.1 He refused and was arrogant and became of the disbelievers.","tr":"Wa-ith qulna lilmala-ikatiosjudoo li-adama fasajadoo illa ibleesa abawastakbara wakana mina alkafireen","juz":1,"page":6},{"s":2,"a":35,"key":"2:35","ar":"وَقُلْنَا يَـٰٓـَٔادَمُ ٱسْكُنْ أَنتَ وَزَوْجُكَ ٱلْجَنَّةَ وَكُلَا مِنْهَا رَغَدًا حَيْثُ شِئْتُمَا وَلَا تَقْرَبَا هَـٰذِهِ ٱلشَّجَرَةَ فَتَكُونَا مِنَ ٱلظَّـٰلِمِينَ","en":"And We said, \"O Adam, dwell, you and your wife, in Paradise and eat therefrom in [ease and] abundance from wherever you will. But do not approach this tree, lest you be among the wrongdoers.\"","tr":"Waqulna ya adamu oskunanta wazawjuka aljannata wakula minha raghadan haythushi/tuma wala taqraba hathihi ashshajaratafatakoona mina aththalimeen","juz":1,"page":6},{"s":2,"a":36,"key":"2:36","ar":"فَأَزَلَّهُمَا ٱلشَّيْطَـٰنُ عَنْهَا فَأَخْرَجَهُمَا مِمَّا كَانَا فِيهِ ۖ وَقُلْنَا ٱهْبِطُوا۟ بَعْضُكُمْ لِبَعْضٍ عَدُوٌّ ۖ وَلَكُمْ فِى ٱلْأَرْضِ مُسْتَقَرٌّ وَمَتَـٰعٌ إِلَىٰ حِينٍ","en":"But Satan caused them to slip out of it and removed them from that [condition] in which they had been. And We said, \"Go down, [all of you], as enemies to one another, and you will have upon the earth a place of settlement and provision for a time.\"","tr":"Faazallahuma ashshaytanuAAanha faakhrajahuma mimma kanafeehi waqulna ihbitoo baAAdukum libaAAdinAAaduwwun walakum fee al-ardi mustaqarrun wamataAAunila heen","juz":1,"page":6},{"s":2,"a":37,"key":"2:37","ar":"فَتَلَقَّىٰٓ ءَادَمُ مِن رَّبِّهِۦ كَلِمَـٰتٍ فَتَابَ عَلَيْهِ ۚ إِنَّهُۥ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ","en":"Then Adam received from his Lord [some] words,1 and He accepted his repentance. Indeed, it is He who is the Accepting of Repentance,2 the Merciful.","tr":"Fatalaqqa adamu min rabbihikalimatin fataba AAalayhi innahu huwa attawwabuarraheem","juz":1,"page":6},{"s":2,"a":38,"key":"2:38","ar":"قُلْنَا ٱهْبِطُوا۟ مِنْهَا جَمِيعًا ۖ فَإِمَّا يَأْتِيَنَّكُم مِّنِّى هُدًى فَمَن تَبِعَ هُدَاىَ فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"We said, \"Go down from it, all of you. And when guidance comes to you from Me, whoever follows My guidance - there will be no fear concerning them, nor will they grieve.","tr":"Qulna ihbitoo minhajameeAAan fa-imma ya/tiyannakum minnee hudan faman tabiAAahudaya fala khawfun AAalayhim wala hum yahzanoon","juz":1,"page":7},{"s":2,"a":39,"key":"2:39","ar":"وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَـٰتِنَآ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"And those who disbelieve and deny Our signs - those will be companions of the Fire; they will abide therein eternally.\"","tr":"Wallatheena kafaroo wakaththaboobi-ayatina ola-ika as-habuannari hum feeha khalidoon","juz":1,"page":7},{"s":2,"a":40,"key":"2:40","ar":"يَـٰبَنِىٓ إِسْرَٰٓءِيلَ ٱذْكُرُوا۟ نِعْمَتِىَ ٱلَّتِىٓ أَنْعَمْتُ عَلَيْكُمْ وَأَوْفُوا۟ بِعَهْدِىٓ أُوفِ بِعَهْدِكُمْ وَإِيَّـٰىَ فَٱرْهَبُونِ","en":"O Children of Israel, remember My favor which I have bestowed upon you and fulfill My covenant [upon you] that I will fulfill your covenant [from Me], and be afraid of [only] Me.","tr":"Ya banee isra-eela othkurooniAAmatiya allatee anAAamtu AAalaykum waawfoo biAAahdee oofibiAAahdikum wa-iyyaya farhaboon","juz":1,"page":7},{"s":2,"a":41,"key":"2:41","ar":"وَءَامِنُوا۟ بِمَآ أَنزَلْتُ مُصَدِّقًا لِّمَا مَعَكُمْ وَلَا تَكُونُوٓا۟ أَوَّلَ كَافِرٍۭ بِهِۦ ۖ وَلَا تَشْتَرُوا۟ بِـَٔايَـٰتِى ثَمَنًا قَلِيلًا وَإِيَّـٰىَ فَٱتَّقُونِ","en":"And believe in what I have sent down confirming that which is [already] with you, and be not the first to disbelieve in it. And do not exchange My signs for a small price, and fear [only] Me.","tr":"Waaminoo bima anzaltu musaddiqanlima maAAakum wala takoonoo awwala kafirinbihi wala tashtaroo bi-ayatee thamananqaleelan wa-iyyaya fattaqoon","juz":1,"page":7},{"s":2,"a":42,"key":"2:42","ar":"وَلَا تَلْبِسُوا۟ ٱلْحَقَّ بِٱلْبَـٰطِلِ وَتَكْتُمُوا۟ ٱلْحَقَّ وَأَنتُمْ تَعْلَمُونَ","en":"And do not mix the truth with falsehood or conceal the truth while you know [it].","tr":"Wala talbisoo alhaqqa bilbatiliwataktumoo alhaqqa waantum taAAlamoon","juz":1,"page":7},{"s":2,"a":43,"key":"2:43","ar":"وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَٱرْكَعُوا۟ مَعَ ٱلرَّٰكِعِينَ","en":"And establish prayer and give zakāh1 and bow with those who bow [in worship and obedience].","tr":"Waaqeemoo assalata waatooazzakata warkaAAoo maAAa arrakiAAeen","juz":1,"page":7},{"s":2,"a":44,"key":"2:44","ar":"۞ أَتَأْمُرُونَ ٱلنَّاسَ بِٱلْبِرِّ وَتَنسَوْنَ أَنفُسَكُمْ وَأَنتُمْ تَتْلُونَ ٱلْكِتَـٰبَ ۚ أَفَلَا تَعْقِلُونَ","en":"Do you order righteousness of the people and forget1 yourselves while you recite the Scripture? Then will you not reason?","tr":"Ata/muroona annasa bilbirriwatansawna anfusakum waantum tatloona alkitaba afalataAAqiloon","juz":1,"page":7},{"s":2,"a":45,"key":"2:45","ar":"وَٱسْتَعِينُوا۟ بِٱلصَّبْرِ وَٱلصَّلَوٰةِ ۚ وَإِنَّهَا لَكَبِيرَةٌ إِلَّا عَلَى ٱلْخَـٰشِعِينَ","en":"And seek help through patience and prayer; and indeed, it is difficult except for the humbly submissive [to Allāh]","tr":"WastaAAeenoo bissabriwassalati wa-innaha lakabeeratunilla AAala alkhashiAAeen","juz":1,"page":7},{"s":2,"a":46,"key":"2:46","ar":"ٱلَّذِينَ يَظُنُّونَ أَنَّهُم مُّلَـٰقُوا۟ رَبِّهِمْ وَأَنَّهُمْ إِلَيْهِ رَٰجِعُونَ","en":"Who are certain that they will meet their Lord and that they will return to Him.","tr":"Allatheena yathunnoonaannahum mulaqoo rabbihim waannahum ilayhi rajiAAoon","juz":1,"page":7},{"s":2,"a":47,"key":"2:47","ar":"يَـٰبَنِىٓ إِسْرَٰٓءِيلَ ٱذْكُرُوا۟ نِعْمَتِىَ ٱلَّتِىٓ أَنْعَمْتُ عَلَيْكُمْ وَأَنِّى فَضَّلْتُكُمْ عَلَى ٱلْعَـٰلَمِينَ","en":"O Children of Israel, remember My favor that I have bestowed upon you and that I preferred you over the worlds [i.e., peoples].","tr":"Ya banee isra-eela othkurooniAAmatiya allatee anAAamtu AAalaykum waannee faddaltukumAAala alAAalameen","juz":1,"page":7},{"s":2,"a":48,"key":"2:48","ar":"وَٱتَّقُوا۟ يَوْمًا لَّا تَجْزِى نَفْسٌ عَن نَّفْسٍ شَيْـًٔا وَلَا يُقْبَلُ مِنْهَا شَفَـٰعَةٌ وَلَا يُؤْخَذُ مِنْهَا عَدْلٌ وَلَا هُمْ يُنصَرُونَ","en":"And fear a Day when no soul will suffice for another soul1 at all, nor will intercession be accepted from it, nor will compensation be taken from it, nor will they be aided.","tr":"Wattaqoo yawman la tajzeenafsun AAan nafsin shay-an wala yuqbalu minha shafaAAatunwala yu/khathu minha AAadlun wala humyunsaroon","juz":1,"page":7},{"s":2,"a":49,"key":"2:49","ar":"وَإِذْ نَجَّيْنَـٰكُم مِّنْ ءَالِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ٱلْعَذَابِ يُذَبِّحُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْ ۚ وَفِى ذَٰلِكُم بَلَآءٌ مِّن رَّبِّكُمْ عَظِيمٌ","en":"And [recall] when We saved you [i.e., your forefathers] from the people of Pharaoh, who afflicted you with the worst torment, slaughtering your [newborn] sons and keeping your females alive. And in that was a great trial from your Lord.","tr":"Wa-ith najjaynakum min alifirAAawna yasoomoonakum soo-a alAAathabi yuthabbihoonaabnaakum wayastahyoona nisaakum wafee thalikumbalaon min rabbikum AAatheem","juz":1,"page":8},{"s":2,"a":50,"key":"2:50","ar":"وَإِذْ فَرَقْنَا بِكُمُ ٱلْبَحْرَ فَأَنجَيْنَـٰكُمْ وَأَغْرَقْنَآ ءَالَ فِرْعَوْنَ وَأَنتُمْ تَنظُرُونَ","en":"And [recall] when We parted the sea for you and saved you and drowned the people of Pharaoh while you were looking on.","tr":"Wa-ith faraqna bikumu albahrafaanjaynakum waaghraqna ala firAAawnawaantum tanthuroon","juz":1,"page":8},{"s":2,"a":51,"key":"2:51","ar":"وَإِذْ وَٰعَدْنَا مُوسَىٰٓ أَرْبَعِينَ لَيْلَةً ثُمَّ ٱتَّخَذْتُمُ ٱلْعِجْلَ مِنۢ بَعْدِهِۦ وَأَنتُمْ ظَـٰلِمُونَ","en":"And [recall] when We made an appointment with Moses for forty nights. Then you took [for worship] the calf after him [i.e., his departure], while you were wrongdoers.","tr":"Wa-ith waAAadna moosaarbaAAeena laylatan thumma ittakhathtumu alAAijla minbaAAdihi waantum thalimoon","juz":1,"page":8},{"s":2,"a":52,"key":"2:52","ar":"ثُمَّ عَفَوْنَا عَنكُم مِّنۢ بَعْدِ ذَٰلِكَ لَعَلَّكُمْ تَشْكُرُونَ","en":"Then We forgave you after that so perhaps you would be grateful.","tr":"Thumma AAafawna AAankum min baAAdi thalikalaAAallakum tashkuroon","juz":1,"page":8},{"s":2,"a":53,"key":"2:53","ar":"وَإِذْ ءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ وَٱلْفُرْقَانَ لَعَلَّكُمْ تَهْتَدُونَ","en":"And [recall] when We gave Moses the Scripture and criterion1 that perhaps you would be guided.","tr":"Wa-ith atayna moosaalkitaba walfurqana laAAallakum tahtadoon","juz":1,"page":8},{"s":2,"a":54,"key":"2:54","ar":"وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِۦ يَـٰقَوْمِ إِنَّكُمْ ظَلَمْتُمْ أَنفُسَكُم بِٱتِّخَاذِكُمُ ٱلْعِجْلَ فَتُوبُوٓا۟ إِلَىٰ بَارِئِكُمْ فَٱقْتُلُوٓا۟ أَنفُسَكُمْ ذَٰلِكُمْ خَيْرٌ لَّكُمْ عِندَ بَارِئِكُمْ فَتَابَ عَلَيْكُمْ ۚ إِنَّهُۥ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ","en":"And [recall] when Moses said to his people, \"O my people, indeed you have wronged yourselves by your taking of the calf [for worship]. So repent to your Creator and kill yourselves [i.e., the guilty among you]. That is best for [all of] you in the sight of your Creator.\" Then He accepted your repentance; indeed, He is the Accepting of Repentance, the Merciful.","tr":"Wa-ith qala moosaliqawmihi ya qawmi innakum thalamtumanfusakum bittikhathikumu alAAijla fatooboo ilabari-ikum faqtuloo anfusakum thalikumkhayrun lakum AAinda bari-ikum fataba AAalaykuminnahu huwa attawwabu arraheem","juz":1,"page":8},{"s":2,"a":55,"key":"2:55","ar":"وَإِذْ قُلْتُمْ يَـٰمُوسَىٰ لَن نُّؤْمِنَ لَكَ حَتَّىٰ نَرَى ٱللَّهَ جَهْرَةً فَأَخَذَتْكُمُ ٱلصَّـٰعِقَةُ وَأَنتُمْ تَنظُرُونَ","en":"And [recall] when you said, \"O Moses, we will never believe you until we see Allāh outright\"; so the thunderbolt took you while you were looking on.","tr":"Wa-ith qultum ya moosalan nu/mina laka hatta nara Allahajahratan faakhathatkumu assaAAiqatu waantumtanthuroon","juz":1,"page":8},{"s":2,"a":56,"key":"2:56","ar":"ثُمَّ بَعَثْنَـٰكُم مِّنۢ بَعْدِ مَوْتِكُمْ لَعَلَّكُمْ تَشْكُرُونَ","en":"Then We revived you after your death that perhaps you would be grateful.","tr":"Thumma baAAathnakum min baAAdimawtikum laAAallakum tashkuroon","juz":1,"page":8},{"s":2,"a":57,"key":"2:57","ar":"وَظَلَّلْنَا عَلَيْكُمُ ٱلْغَمَامَ وَأَنزَلْنَا عَلَيْكُمُ ٱلْمَنَّ وَٱلسَّلْوَىٰ ۖ كُلُوا۟ مِن طَيِّبَـٰتِ مَا رَزَقْنَـٰكُمْ ۖ وَمَا ظَلَمُونَا وَلَـٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ","en":"And We shaded you with clouds and sent down to you manna and quails, [saying], \"Eat from the good things with which We have provided you.\" And they wronged Us not - but they were [only] wronging themselves.","tr":"Wathallalna AAalaykumualghamama waanzalna AAalaykumu almanna wassalwakuloo min tayyibati ma razaqnakum wamathalamoona walakin kanooanfusahum yathlimoon","juz":1,"page":8},{"s":2,"a":58,"key":"2:58","ar":"وَإِذْ قُلْنَا ٱدْخُلُوا۟ هَـٰذِهِ ٱلْقَرْيَةَ فَكُلُوا۟ مِنْهَا حَيْثُ شِئْتُمْ رَغَدًا وَٱدْخُلُوا۟ ٱلْبَابَ سُجَّدًا وَقُولُوا۟ حِطَّةٌ نَّغْفِرْ لَكُمْ خَطَـٰيَـٰكُمْ ۚ وَسَنَزِيدُ ٱلْمُحْسِنِينَ","en":"And [recall] when We said, \"Enter this city [i.e., Jerusalem] and eat from it wherever you will in [ease and] abundance, and enter the gate bowing humbly1 and say, 'Relieve us of our burdens [i.e., sins].' We will [then] forgive your sins for you, and We will increase the doers of good [in goodness and reward].\"","tr":"Wa-ith qulna odkhuloo hathihialqaryata fakuloo minha haythu shi/tum raghadan wadkhulooalbaba sujjadan waqooloo hittatun naghfirlakum khatayakum wasanazeedu almuhsineen","juz":1,"page":9},{"s":2,"a":59,"key":"2:59","ar":"فَبَدَّلَ ٱلَّذِينَ ظَلَمُوا۟ قَوْلًا غَيْرَ ٱلَّذِى قِيلَ لَهُمْ فَأَنزَلْنَا عَلَى ٱلَّذِينَ ظَلَمُوا۟ رِجْزًا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَفْسُقُونَ","en":"But those who wronged changed [those words] to a statement other than that which had been said to them, so We sent down upon those who wronged a punishment [i.e., plague] from the sky because they were defiantly disobeying.","tr":"Fabaddala allatheena thalamooqawlan ghayra allathee qeela lahum faanzalna AAalaallatheena thalamoo rijzan mina assama-ibima kanoo yafsuqoon","juz":1,"page":9},{"s":2,"a":60,"key":"2:60","ar":"۞ وَإِذِ ٱسْتَسْقَىٰ مُوسَىٰ لِقَوْمِهِۦ فَقُلْنَا ٱضْرِب بِّعَصَاكَ ٱلْحَجَرَ ۖ فَٱنفَجَرَتْ مِنْهُ ٱثْنَتَا عَشْرَةَ عَيْنًا ۖ قَدْ عَلِمَ كُلُّ أُنَاسٍ مَّشْرَبَهُمْ ۖ كُلُوا۟ وَٱشْرَبُوا۟ مِن رِّزْقِ ٱللَّهِ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ","en":"And [recall] when Moses prayed for water for his people, so We said, \"Strike with your staff the stone.\" And there gushed forth from it twelve springs, and every people [i.e., tribe] knew its watering place. \"Eat and drink from the provision of Allāh, and do not commit abuse on the earth, spreading corruption.\"","tr":"Wa-ithi istasqa moosaliqawmihi faqulna idrib biAAasaka alhajarafanfajarat minhu ithnata AAashrata AAaynan qadAAalima kullu onasin mashrabahum kuloo washraboomin rizqi Allahi wala taAAthaw fee al-ardimufsideen","juz":1,"page":9},{"s":2,"a":61,"key":"2:61","ar":"وَإِذْ قُلْتُمْ يَـٰمُوسَىٰ لَن نَّصْبِرَ عَلَىٰ طَعَامٍ وَٰحِدٍ فَٱدْعُ لَنَا رَبَّكَ يُخْرِجْ لَنَا مِمَّا تُنۢبِتُ ٱلْأَرْضُ مِنۢ بَقْلِهَا وَقِثَّآئِهَا وَفُومِهَا وَعَدَسِهَا وَبَصَلِهَا ۖ قَالَ أَتَسْتَبْدِلُونَ ٱلَّذِى هُوَ أَدْنَىٰ بِٱلَّذِى هُوَ خَيْرٌ ۚ ٱهْبِطُوا۟ مِصْرًا فَإِنَّ لَكُم مَّا سَأَلْتُمْ ۗ وَضُرِبَتْ عَلَيْهِمُ ٱلذِّلَّةُ وَٱلْمَسْكَنَةُ وَبَآءُو بِغَضَبٍ مِّنَ ٱللَّهِ ۗ ذَٰلِكَ بِأَنَّهُمْ كَانُوا۟ يَكْفُرُونَ بِـَٔايَـٰتِ ٱللَّهِ وَيَقْتُلُونَ ٱلنَّبِيِّـۧنَ بِغَيْرِ ٱلْحَقِّ ۗ ذَٰلِكَ بِمَا عَصَوا۟ وَّكَانُوا۟ يَعْتَدُونَ","en":"And [recall] when you said, \"O Moses, we can never endure one [kind of] food. So call upon your Lord to bring forth for us from the earth its green herbs and its cucumbers and its garlic and its lentils and its onions.\" [Moses] said, \"Would you exchange what is better for what is less? Go into [any] settlement and indeed, you will have what you have asked.\" And they were covered with humiliation and poverty and returned with anger from Allāh [upon them]. That was because they [repeatedly] disbelieved in the signs of Allāh and killed the prophets without right. That was because they disobeyed and were [habitually] transgressing.","tr":"Wa-ith qultum ya moosalan nasbira AAala taAAamin wahidinfadAAu lana rabbaka yukhrij lana mimmatunbitu al-ardu min baqliha waqiththa-ihawafoomiha waAAadasiha wabasaliha qalaatastabdiloona allathee huwa adna billatheehuwa khayrun ihbitoo misran fa-inna lakum masaaltum waduribat AAalayhimu aththillatu walmaskanatuwabaoo bighadabin mina Allahi thalikabi-annahum kanoo yakfuroona bi-ayati Allahiwayaqtuloona annabiyyeena bighayri alhaqqi thalikabima AAasaw wakanoo yaAAtadoon","juz":1,"page":9},{"s":2,"a":62,"key":"2:62","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَادُوا۟ وَٱلنَّصَـٰرَىٰ وَٱلصَّـٰبِـِٔينَ مَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ وَعَمِلَ صَـٰلِحًا فَلَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"Indeed, those who believed and those who were Jews or Christians or Sabeans [before Prophet Muḥammad (ﷺ)] - those [among them] who believed in Allāh and the Last Day and did righteousness - will have their reward with their Lord, and no fear will there be concerning them, nor will they grieve1.","tr":"Inna allatheena amanoo wallatheenahadoo wannasara wassabi-eenaman amana biAllahi walyawmi al-akhiriwaAAamila salihan falahum ajruhum AAinda rabbihimwala khawfun AAalayhim wala hum yahzanoon","juz":1,"page":10},{"s":2,"a":63,"key":"2:63","ar":"وَإِذْ أَخَذْنَا مِيثَـٰقَكُمْ وَرَفَعْنَا فَوْقَكُمُ ٱلطُّورَ خُذُوا۟ مَآ ءَاتَيْنَـٰكُم بِقُوَّةٍ وَٱذْكُرُوا۟ مَا فِيهِ لَعَلَّكُمْ تَتَّقُونَ","en":"And [recall] when We took your covenant, [O Children of Israel, to abide by the Torah] and We raised over you the mount, [saying], \"Take what We have given you with determination and remember what is in it that perhaps you may become righteous.\"","tr":"Wa-ith akhathna meethaqakumwarafaAAna fawqakumu attoora khuthooma ataynakum biquwwatin wathkurooma feehi laAAallakum tattaqoon","juz":1,"page":10},{"s":2,"a":64,"key":"2:64","ar":"ثُمَّ تَوَلَّيْتُم مِّنۢ بَعْدِ ذَٰلِكَ ۖ فَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ لَكُنتُم مِّنَ ٱلْخَـٰسِرِينَ","en":"Then you turned away after that. And if not for the favor of Allāh upon you and His mercy, you would have been among the losers.","tr":"Thumma tawallaytum min baAAdi thalikafalawla fadlu Allahi AAalaykum warahmatuhulakuntum mina alkhasireen","juz":1,"page":10},{"s":2,"a":65,"key":"2:65","ar":"وَلَقَدْ عَلِمْتُمُ ٱلَّذِينَ ٱعْتَدَوْا۟ مِنكُمْ فِى ٱلسَّبْتِ فَقُلْنَا لَهُمْ كُونُوا۟ قِرَدَةً خَـٰسِـِٔينَ","en":"And you had already known about those who transgressed among you concerning the sabbath, and We said to them, \"Be apes, despised.\"","tr":"Walaqad AAalimtumu allatheenaiAAtadaw minkum fee assabti faqulna lahum koonooqiradatan khasi-een","juz":1,"page":10},{"s":2,"a":66,"key":"2:66","ar":"فَجَعَلْنَـٰهَا نَكَـٰلًا لِّمَا بَيْنَ يَدَيْهَا وَمَا خَلْفَهَا وَمَوْعِظَةً لِّلْمُتَّقِينَ","en":"And We made it a deterrent punishment for those who were present and those who succeeded [them] and a lesson for those who fear Allāh.","tr":"FajaAAalnaha nakalanlima bayna yadayha wama khalfahawamawAAithatan lilmuttaqeen","juz":1,"page":10},{"s":2,"a":67,"key":"2:67","ar":"وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِۦٓ إِنَّ ٱللَّهَ يَأْمُرُكُمْ أَن تَذْبَحُوا۟ بَقَرَةً ۖ قَالُوٓا۟ أَتَتَّخِذُنَا هُزُوًا ۖ قَالَ أَعُوذُ بِٱللَّهِ أَنْ أَكُونَ مِنَ ٱلْجَـٰهِلِينَ","en":"And [recall] when Moses said to his people, \"Indeed, Allāh commands you to slaughter a cow.\" They said, \"Do you take us in ridicule?\" He said, \"I seek refuge in Allāh from being among the ignorant.\"","tr":"Wa-ith qala moosaliqawmihi inna Allaha ya/murukum an tathbahoobaqaratan qaloo atattakhithuna huzuwan qalaaAAoothu biAllahi an akoona mina aljahileen","juz":1,"page":10},{"s":2,"a":68,"key":"2:68","ar":"قَالُوا۟ ٱدْعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا هِىَ ۚ قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٌ لَّا فَارِضٌ وَلَا بِكْرٌ عَوَانٌۢ بَيْنَ ذَٰلِكَ ۖ فَٱفْعَلُوا۟ مَا تُؤْمَرُونَ","en":"They said, \"Call upon your Lord to make clear to us what it is.\" [Moses] said, \"[Allāh] says, 'It is a cow which is neither old nor virgin, but median between that,' so do what you are commanded.\"","tr":"Qaloo odAAu lana rabbakayubayyin lana ma hiya qala innahu yaqooluinnaha baqaratun la faridun walabikrun AAawanun bayna thalika fafAAaloo matu/maroon","juz":1,"page":10},{"s":2,"a":69,"key":"2:69","ar":"قَالُوا۟ ٱدْعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا لَوْنُهَا ۚ قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٌ صَفْرَآءُ فَاقِعٌ لَّوْنُهَا تَسُرُّ ٱلنَّـٰظِرِينَ","en":"They said, \"Call upon your Lord to show us what is her color.\" He said, \"He says, 'It is a yellow cow, bright in color - pleasing to the observers.'\"","tr":"Qaloo odAAu lana rabbakayubayyin lana ma lawnuha qala innahuyaqoolu innaha baqaratun safrao faqiAAunlawnuha tasurru annathireen","juz":1,"page":10},{"s":2,"a":70,"key":"2:70","ar":"قَالُوا۟ ٱدْعُ لَنَا رَبَّكَ يُبَيِّن لَّنَا مَا هِىَ إِنَّ ٱلْبَقَرَ تَشَـٰبَهَ عَلَيْنَا وَإِنَّآ إِن شَآءَ ٱللَّهُ لَمُهْتَدُونَ","en":"They said, \"Call upon your Lord to make clear to us what it is. Indeed, [all] cows look alike to us. And indeed we, if Allāh wills, will be guided.\"","tr":"Qaloo odAAu lana rabbakayubayyin lana ma hiya inna albaqara tashabahaAAalayna wa-inna in shaa Allahulamuhtadoon","juz":1,"page":11},{"s":2,"a":71,"key":"2:71","ar":"قَالَ إِنَّهُۥ يَقُولُ إِنَّهَا بَقَرَةٌ لَّا ذَلُولٌ تُثِيرُ ٱلْأَرْضَ وَلَا تَسْقِى ٱلْحَرْثَ مُسَلَّمَةٌ لَّا شِيَةَ فِيهَا ۚ قَالُوا۟ ٱلْـَٔـٰنَ جِئْتَ بِٱلْحَقِّ ۚ فَذَبَحُوهَا وَمَا كَادُوا۟ يَفْعَلُونَ","en":"He said, \"He says, 'It is a cow neither trained to plow the earth nor to irrigate the field, one free from fault with no spot upon her.'\" They said, \"Now you have come with the truth.\" So they slaughtered her, but they could hardly do it.","tr":"Qala innahu yaqoolu innahabaqaratun la thaloolun tutheeru al-arda walatasqee alhartha musallamatun la shiyata feehaqaloo al-ana ji/ta bilhaqqi fathabahoohawama kadoo yafAAaloon","juz":1,"page":11},{"s":2,"a":72,"key":"2:72","ar":"وَإِذْ قَتَلْتُمْ نَفْسًا فَٱدَّٰرَْٰٔتُمْ فِيهَا ۖ وَٱللَّهُ مُخْرِجٌ مَّا كُنتُمْ تَكْتُمُونَ","en":"And [recall] when you slew a man and disputed1 over it, but Allāh was to bring out that which you were concealing.","tr":"Wa-ith qataltum nafsan faddara/tumfeeha wallahu mukhrijun ma kuntumtaktumoon","juz":1,"page":11},{"s":2,"a":73,"key":"2:73","ar":"فَقُلْنَا ٱضْرِبُوهُ بِبَعْضِهَا ۚ كَذَٰلِكَ يُحْىِ ٱللَّهُ ٱلْمَوْتَىٰ وَيُرِيكُمْ ءَايَـٰتِهِۦ لَعَلَّكُمْ تَعْقِلُونَ","en":"So We said, \"Strike him [i.e., the slain man] with part of it.\"1 Thus does Allāh bring the dead to life, and He shows you His signs that you might reason.","tr":"Faqulna idriboohu bibaAAdihakathalika yuhyee Allahu almawtawayureekum ayatihi laAAallakum taAAqiloon","juz":1,"page":11},{"s":2,"a":74,"key":"2:74","ar":"ثُمَّ قَسَتْ قُلُوبُكُم مِّنۢ بَعْدِ ذَٰلِكَ فَهِىَ كَٱلْحِجَارَةِ أَوْ أَشَدُّ قَسْوَةً ۚ وَإِنَّ مِنَ ٱلْحِجَارَةِ لَمَا يَتَفَجَّرُ مِنْهُ ٱلْأَنْهَـٰرُ ۚ وَإِنَّ مِنْهَا لَمَا يَشَّقَّقُ فَيَخْرُجُ مِنْهُ ٱلْمَآءُ ۚ وَإِنَّ مِنْهَا لَمَا يَهْبِطُ مِنْ خَشْيَةِ ٱللَّهِ ۗ وَمَا ٱللَّهُ بِغَـٰفِلٍ عَمَّا تَعْمَلُونَ","en":"Then your hearts became hardened after that, being like stones or even harder. For indeed, there are stones from which rivers burst forth, and there are some of them that split open and water comes out, and there are some of them that fall down for fear of Allāh. And Allāh is not unaware of what you do.","tr":"Thumma qasat quloobukum min baAAdi thalikafahiya kalhijarati aw ashaddu qaswatanwa-inna mina alhijarati lama yatafajjaruminhu al-anharu wa-inna minha lamayashshaqqaqu fayakhruju minhu almao wa-inna minhalama yahbitu min khashyati Allahi wamaAllahu bighafilin AAamma taAAmaloon","juz":1,"page":11},{"s":2,"a":75,"key":"2:75","ar":"۞ أَفَتَطْمَعُونَ أَن يُؤْمِنُوا۟ لَكُمْ وَقَدْ كَانَ فَرِيقٌ مِّنْهُمْ يَسْمَعُونَ كَلَـٰمَ ٱللَّهِ ثُمَّ يُحَرِّفُونَهُۥ مِنۢ بَعْدِ مَا عَقَلُوهُ وَهُمْ يَعْلَمُونَ","en":"Do you covet [the hope, O believers], that they would believe for you while a party of them used to hear the words of Allāh and then distort it [i.e., the Torah] after they had understood it while they were knowing?","tr":"AfatatmaAAoona an yu/minoo lakumwaqad kana fareequn minhum yasmaAAoona kalama Allahithumma yuharrifoonahu min baAAdi ma AAaqaloohuwahum yaAAlamoon","juz":1,"page":11},{"s":2,"a":76,"key":"2:76","ar":"وَإِذَا لَقُوا۟ ٱلَّذِينَ ءَامَنُوا۟ قَالُوٓا۟ ءَامَنَّا وَإِذَا خَلَا بَعْضُهُمْ إِلَىٰ بَعْضٍ قَالُوٓا۟ أَتُحَدِّثُونَهُم بِمَا فَتَحَ ٱللَّهُ عَلَيْكُمْ لِيُحَآجُّوكُم بِهِۦ عِندَ رَبِّكُمْ ۚ أَفَلَا تَعْقِلُونَ","en":"And when they meet those who believe, they say, \"We have believed\"; but when they are alone with one another, they say, \"Do you talk to them about what Allāh has revealed to you so they can argue with you about it before your Lord?\" Then will you not reason?","tr":"Wa-itha laqoo allatheena amanooqaloo amanna wa-itha khalabaAAduhum ila baAAdin qaloo atuhaddithoonahumbima fataha Allahu AAalaykum liyuhajjookumbihi AAinda rabbikum afala taAAqiloon","juz":1,"page":11},{"s":2,"a":77,"key":"2:77","ar":"أَوَلَا يَعْلَمُونَ أَنَّ ٱللَّهَ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ","en":"But do they not know that Allāh knows what they conceal and what they declare?","tr":"Awa la yaAAlamoona anna AllahayaAAlamu ma yusirroona wama yuAAlinoon","juz":1,"page":12},{"s":2,"a":78,"key":"2:78","ar":"وَمِنْهُمْ أُمِّيُّونَ لَا يَعْلَمُونَ ٱلْكِتَـٰبَ إِلَّآ أَمَانِىَّ وَإِنْ هُمْ إِلَّا يَظُنُّونَ","en":"And among them are unlettered ones who do not know the Scripture except [indulgement in] wishful thinking, but they are only assuming.","tr":"Waminhum ommiyyoona la yaAAlamoonaalkitaba illa amaniyya wa-in hum illayathunnoon","juz":1,"page":12},{"s":2,"a":79,"key":"2:79","ar":"فَوَيْلٌ لِّلَّذِينَ يَكْتُبُونَ ٱلْكِتَـٰبَ بِأَيْدِيهِمْ ثُمَّ يَقُولُونَ هَـٰذَا مِنْ عِندِ ٱللَّهِ لِيَشْتَرُوا۟ بِهِۦ ثَمَنًا قَلِيلًا ۖ فَوَيْلٌ لَّهُم مِّمَّا كَتَبَتْ أَيْدِيهِمْ وَوَيْلٌ لَّهُم مِّمَّا يَكْسِبُونَ","en":"So woe1 to those who write the \"scripture\" with their own hands, then say, \"This is from Allāh,\" in order to exchange it for a small price. Woe to them for what their hands have written and woe to them for what they earn.","tr":"Fawaylun lillatheena yaktuboona alkitababi-aydeehim thumma yaqooloona hatha min AAindi Allahiliyashtaroo bihi thamanan qaleelan fawaylun lahum mimmakatabat aydeehim wawaylun lahum mimma yaksiboon","juz":1,"page":12},{"s":2,"a":80,"key":"2:80","ar":"وَقَالُوا۟ لَن تَمَسَّنَا ٱلنَّارُ إِلَّآ أَيَّامًا مَّعْدُودَةً ۚ قُلْ أَتَّخَذْتُمْ عِندَ ٱللَّهِ عَهْدًا فَلَن يُخْلِفَ ٱللَّهُ عَهْدَهُۥٓ ۖ أَمْ تَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ","en":"And they say, \"Never will the Fire touch us, except for [a few] numbered days.\" Say, \"Have you taken a covenant with Allāh? For Allāh will never break His covenant. Or do you say about Allāh that which you do not know?\"","tr":"Waqaloo lan tamassana annaruilla ayyaman maAAdoodatan qul attakhathtumAAinda Allahi AAahdan falan yukhlifa AllahuAAahdahu am taqooloona AAala Allahi ma lataAAlamoon","juz":1,"page":12},{"s":2,"a":81,"key":"2:81","ar":"بَلَىٰ مَن كَسَبَ سَيِّئَةً وَأَحَـٰطَتْ بِهِۦ خَطِيٓـَٔتُهُۥ فَأُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"Yes, [on the contrary], whoever earns evil and his sin has encompassed him - those are the companions of the Fire; they will abide therein eternally.","tr":"Bala man kasaba sayyi-atan waahatatbihi khatee-atuhu faola-ika as-habu annarihum feeha khalidoon","juz":1,"page":12},{"s":2,"a":82,"key":"2:82","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْجَنَّةِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"But they who believe and do righteous deeds - those are the companions of Paradise; they will abide therein eternally.","tr":"Wallatheena amanoowaAAamiloo assalihati ola-ika as-habualjannati hum feeha khalidoon","juz":1,"page":12},{"s":2,"a":83,"key":"2:83","ar":"وَإِذْ أَخَذْنَا مِيثَـٰقَ بَنِىٓ إِسْرَٰٓءِيلَ لَا تَعْبُدُونَ إِلَّا ٱللَّهَ وَبِٱلْوَٰلِدَيْنِ إِحْسَانًا وَذِى ٱلْقُرْبَىٰ وَٱلْيَتَـٰمَىٰ وَٱلْمَسَـٰكِينِ وَقُولُوا۟ لِلنَّاسِ حُسْنًا وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ ثُمَّ تَوَلَّيْتُمْ إِلَّا قَلِيلًا مِّنكُمْ وَأَنتُم مُّعْرِضُونَ","en":"And [recall] when We took the covenant from the Children of Israel, [enjoining upon them], \"Do not worship except Allāh; and to parents do good and to relatives, orphans, and the needy. And speak to people good [words] and establish prayer and give zakāh.\" Then you turned away, except a few of you, and you were refusing.","tr":"Wa-ith akhathna meethaqabanee isra-eela la taAAbudoona illa Allahawabilwalidayni ihsanan watheealqurba walyatama walmasakeeniwaqooloo linnasi husnan waaqeemoo assalatawaatoo azzakata thumma tawallaytum illaqaleelan minkum waantum muAAridoon","juz":1,"page":12},{"s":2,"a":84,"key":"2:84","ar":"وَإِذْ أَخَذْنَا مِيثَـٰقَكُمْ لَا تَسْفِكُونَ دِمَآءَكُمْ وَلَا تُخْرِجُونَ أَنفُسَكُم مِّن دِيَـٰرِكُمْ ثُمَّ أَقْرَرْتُمْ وَأَنتُمْ تَشْهَدُونَ","en":"And [recall] when We took your covenant, [saying], \"Do not shed your [i.e., each other's] blood or evict one another from your homes.\" Then you acknowledged [this] while you were witnessing.","tr":"Wa-ith akhathna meethaqakumla tasfikoona dimaakum wala tukhrijoonaanfusakum min diyarikum thumma aqrartum waantum tashhadoon","juz":1,"page":13},{"s":2,"a":85,"key":"2:85","ar":"ثُمَّ أَنتُمْ هَـٰٓؤُلَآءِ تَقْتُلُونَ أَنفُسَكُمْ وَتُخْرِجُونَ فَرِيقًا مِّنكُم مِّن دِيَـٰرِهِمْ تَظَـٰهَرُونَ عَلَيْهِم بِٱلْإِثْمِ وَٱلْعُدْوَٰنِ وَإِن يَأْتُوكُمْ أُسَـٰرَىٰ تُفَـٰدُوهُمْ وَهُوَ مُحَرَّمٌ عَلَيْكُمْ إِخْرَاجُهُمْ ۚ أَفَتُؤْمِنُونَ بِبَعْضِ ٱلْكِتَـٰبِ وَتَكْفُرُونَ بِبَعْضٍ ۚ فَمَا جَزَآءُ مَن يَفْعَلُ ذَٰلِكَ مِنكُمْ إِلَّا خِزْىٌ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَيَوْمَ ٱلْقِيَـٰمَةِ يُرَدُّونَ إِلَىٰٓ أَشَدِّ ٱلْعَذَابِ ۗ وَمَا ٱللَّهُ بِغَـٰفِلٍ عَمَّا تَعْمَلُونَ","en":"Then, you are those [same ones who are] killing one another and evicting a party of your people from their homes, cooperating against them in sin and aggression. And if they come to you as captives, you ransom them, although their eviction was forbidden to you. So do you believe in part of the Scripture and disbelieve in part? Then what is the recompense for those who do that among you except disgrace in worldly life; and on the Day of Resurrection they will be sent back to the severest of punishment. And Allāh is not unaware of what you do.","tr":"Thumma antum haola-itaqtuloona anfusakum watukhrijoona fareeqan minkum min diyarihimtathaharoona AAalayhim bil-ithmi walAAudwaniwa-in ya/tookum osara tufadoohum wahuwa muharramunAAalaykum ikhrajuhum afatu/minoona bibaAAdi alkitabiwatakfuroona bibaAAdin fama jazao manyafAAalu thalika minkum illa khizyun fee alhayatiaddunya wayawma alqiyamati yuraddoona ilaashaddi alAAathabi wama Allahu bighafilinAAamma taAAmaloon","juz":1,"page":13},{"s":2,"a":86,"key":"2:86","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلْحَيَوٰةَ ٱلدُّنْيَا بِٱلْـَٔاخِرَةِ ۖ فَلَا يُخَفَّفُ عَنْهُمُ ٱلْعَذَابُ وَلَا هُمْ يُنصَرُونَ","en":"Those are the ones who have bought the life of this world [in exchange] for the Hereafter, so the punishment will not be lightened for them, nor will they be aided.","tr":"Ola-ika allatheena ishtarawooalhayata addunya bil-akhiratifala yukhaffafu AAanhumu alAAathabu wala humyunsaroon","juz":1,"page":13},{"s":2,"a":87,"key":"2:87","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ وَقَفَّيْنَا مِنۢ بَعْدِهِۦ بِٱلرُّسُلِ ۖ وَءَاتَيْنَا عِيسَى ٱبْنَ مَرْيَمَ ٱلْبَيِّنَـٰتِ وَأَيَّدْنَـٰهُ بِرُوحِ ٱلْقُدُسِ ۗ أَفَكُلَّمَا جَآءَكُمْ رَسُولٌۢ بِمَا لَا تَهْوَىٰٓ أَنفُسُكُمُ ٱسْتَكْبَرْتُمْ فَفَرِيقًا كَذَّبْتُمْ وَفَرِيقًا تَقْتُلُونَ","en":"And We did certainly give Moses the Scripture [i.e., the Torah] and followed up after him with messengers. And We gave Jesus, the son of Mary, clear proofs and supported him with the Pure Spirit [i.e., the angel Gabriel]. But is it [not] that every time a messenger came to you, [O Children of Israel], with what your souls did not desire, you were arrogant? And a party [of messengers] you denied and another party you killed.","tr":"Walaqad atayna moosaalkitaba waqaffayna min baAAdihi birrusuliwaatayna AAeesa ibna maryama albayyinatiwaayyadnahu biroohi alqudusi afakullama jaakumrasoolun bima la tahwa anfusukumuistakbartum fafareeqan kaththabtum wafareeqan taqtuloon","juz":1,"page":13},{"s":2,"a":88,"key":"2:88","ar":"وَقَالُوا۟ قُلُوبُنَا غُلْفٌۢ ۚ بَل لَّعَنَهُمُ ٱللَّهُ بِكُفْرِهِمْ فَقَلِيلًا مَّا يُؤْمِنُونَ","en":"And they said, \"Our hearts are wrapped.\"1 But, [in fact], Allāh has cursed them for their disbelief, so little is it that they believe.","tr":"Waqaloo quloobuna ghulfun ballaAAanahumu Allahu bikufrihim faqaleelan mayu/minoon","juz":1,"page":13},{"s":2,"a":89,"key":"2:89","ar":"وَلَمَّا جَآءَهُمْ كِتَـٰبٌ مِّنْ عِندِ ٱللَّهِ مُصَدِّقٌ لِّمَا مَعَهُمْ وَكَانُوا۟ مِن قَبْلُ يَسْتَفْتِحُونَ عَلَى ٱلَّذِينَ كَفَرُوا۟ فَلَمَّا جَآءَهُم مَّا عَرَفُوا۟ كَفَرُوا۟ بِهِۦ ۚ فَلَعْنَةُ ٱللَّهِ عَلَى ٱلْكَـٰفِرِينَ","en":"And when there came to them a Book [i.e., the Qur’ān] from Allāh confirming that which was with them - although before they used to pray for victory against those who disbelieved - but [then] when there came to them that which they recognized, they disbelieved in it; so the curse of Allāh will be upon the disbelievers.","tr":"Walamma jaahum kitabunmin AAindi Allahi musaddiqun lima maAAahumwakanoo min qablu yastaftihoona AAala allatheenakafaroo falamma jaahum ma AAarafoo kafaroobihi falaAAnatu Allahi AAala alkafireen","juz":1,"page":14},{"s":2,"a":90,"key":"2:90","ar":"بِئْسَمَا ٱشْتَرَوْا۟ بِهِۦٓ أَنفُسَهُمْ أَن يَكْفُرُوا۟ بِمَآ أَنزَلَ ٱللَّهُ بَغْيًا أَن يُنَزِّلَ ٱللَّهُ مِن فَضْلِهِۦ عَلَىٰ مَن يَشَآءُ مِنْ عِبَادِهِۦ ۖ فَبَآءُو بِغَضَبٍ عَلَىٰ غَضَبٍ ۚ وَلِلْكَـٰفِرِينَ عَذَابٌ مُّهِينٌ","en":"How wretched is that for which they sold themselves - that they would disbelieve in what Allāh has revealed through [their] outrage that Allāh would send down His favor upon whom He wills from among His servants. So they returned having [earned] wrath upon wrath. And for the disbelievers is a humiliating punishment.","tr":"Bi/sama ishtaraw bihi anfusahum anyakfuroo bima anzala Allahu baghyan an yunazzilaAllahu min fadlihi AAala man yashaomin AAibadihi fabaoo bighadabin AAalaghadabin walilkafireena AAathabun muheen","juz":1,"page":14},{"s":2,"a":91,"key":"2:91","ar":"وَإِذَا قِيلَ لَهُمْ ءَامِنُوا۟ بِمَآ أَنزَلَ ٱللَّهُ قَالُوا۟ نُؤْمِنُ بِمَآ أُنزِلَ عَلَيْنَا وَيَكْفُرُونَ بِمَا وَرَآءَهُۥ وَهُوَ ٱلْحَقُّ مُصَدِّقًا لِّمَا مَعَهُمْ ۗ قُلْ فَلِمَ تَقْتُلُونَ أَنۢبِيَآءَ ٱللَّهِ مِن قَبْلُ إِن كُنتُم مُّؤْمِنِينَ","en":"And when it is said to them, \"Believe in what Allāh has revealed,\" they say, \"We believe [only] in what was revealed to us.\" And they disbelieve in what came after it, while it is the truth confirming that which is with them. Say, \"Then why did you kill the prophets of Allāh before, if you are [indeed] believers?\"","tr":"Wa-itha qeela lahum aminoo bimaanzala Allahu qaloo nu/minu bima onzilaAAalayna wayakfuroona bima waraahu wahuwa alhaqqumusaddiqan lima maAAahum qul falima taqtuloonaanbiyaa Allahi min qablu in kuntum mu/mineen","juz":1,"page":14},{"s":2,"a":92,"key":"2:92","ar":"۞ وَلَقَدْ جَآءَكُم مُّوسَىٰ بِٱلْبَيِّنَـٰتِ ثُمَّ ٱتَّخَذْتُمُ ٱلْعِجْلَ مِنۢ بَعْدِهِۦ وَأَنتُمْ ظَـٰلِمُونَ","en":"And Moses had certainly brought you clear proofs. Then you took the calf [in worship] after that, while you were wrongdoers.","tr":"Walaqad jaakum moosa bilbayyinatithumma ittakhathtumu alAAijla min baAAdihi waantum thalimoon","juz":1,"page":14},{"s":2,"a":93,"key":"2:93","ar":"وَإِذْ أَخَذْنَا مِيثَـٰقَكُمْ وَرَفَعْنَا فَوْقَكُمُ ٱلطُّورَ خُذُوا۟ مَآ ءَاتَيْنَـٰكُم بِقُوَّةٍ وَٱسْمَعُوا۟ ۖ قَالُوا۟ سَمِعْنَا وَعَصَيْنَا وَأُشْرِبُوا۟ فِى قُلُوبِهِمُ ٱلْعِجْلَ بِكُفْرِهِمْ ۚ قُلْ بِئْسَمَا يَأْمُرُكُم بِهِۦٓ إِيمَـٰنُكُمْ إِن كُنتُم مُّؤْمِنِينَ","en":"And [recall] when We took your covenant and raised over you the mount, [saying], \"Take what We have given you with determination and listen.\" They said [instead], \"We hear and disobey.\" And their hearts absorbed [the worship of] the calf because of their disbelief. Say, \"How wretched is that which your faith enjoins upon you, if you should be believers.\"","tr":"Wa-ith akhathna meethaqakumwarafaAAna fawqakumu attoora khuthooma ataynakum biquwwatin wasmaAAoo qaloosamiAAna waAAasayna waoshriboo feequloobihimu alAAijla bikufrihim qul bi/sama ya/murukumbihi eemanukum in kuntum mu/mineen","juz":1,"page":14},{"s":2,"a":94,"key":"2:94","ar":"قُلْ إِن كَانَتْ لَكُمُ ٱلدَّارُ ٱلْـَٔاخِرَةُ عِندَ ٱللَّهِ خَالِصَةً مِّن دُونِ ٱلنَّاسِ فَتَمَنَّوُا۟ ٱلْمَوْتَ إِن كُنتُمْ صَـٰدِقِينَ","en":"Say, [O Muḥammad], \"If the home of the Hereafter with Allāh is for you alone and not the [other] people, then wish for death, if you should be truthful.\"","tr":"Qul in kanat lakumu addarual-akhiratu AAinda Allahi khalisatanmin dooni annasi fatamannawoo almawta in kuntum sadiqeen","juz":1,"page":15},{"s":2,"a":95,"key":"2:95","ar":"وَلَن يَتَمَنَّوْهُ أَبَدًۢا بِمَا قَدَّمَتْ أَيْدِيهِمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلظَّـٰلِمِينَ","en":"But never will they wish for it, ever, because of what their hands have put forth. And Allāh is Knowing of the wrongdoers.","tr":"Walan yatamannawhu abadan bimaqaddamat aydeehim wallahu AAaleemun biaththalimeen","juz":1,"page":15},{"s":2,"a":96,"key":"2:96","ar":"وَلَتَجِدَنَّهُمْ أَحْرَصَ ٱلنَّاسِ عَلَىٰ حَيَوٰةٍ وَمِنَ ٱلَّذِينَ أَشْرَكُوا۟ ۚ يَوَدُّ أَحَدُهُمْ لَوْ يُعَمَّرُ أَلْفَ سَنَةٍ وَمَا هُوَ بِمُزَحْزِحِهِۦ مِنَ ٱلْعَذَابِ أَن يُعَمَّرَ ۗ وَٱللَّهُ بَصِيرٌۢ بِمَا يَعْمَلُونَ","en":"And you will surely find them the most greedy of people for life - [even] more than those who associate others with Allāh. One of them wishes that he could be granted life a thousand years, but it would not remove him in the least from the [coming] punishment that he should be granted life. And Allāh is Seeing of what they do.","tr":"Walatajidannahum ahrasa annasiAAala hayatin wamina allatheenaashrakoo yawaddu ahaduhum law yuAAammaru alfa sanatin wamahuwa bimuzahzihihi mina alAAathabi anyuAAammara wallahu baseerun bimayaAAmaloon","juz":1,"page":15},{"s":2,"a":97,"key":"2:97","ar":"قُلْ مَن كَانَ عَدُوًّا لِّجِبْرِيلَ فَإِنَّهُۥ نَزَّلَهُۥ عَلَىٰ قَلْبِكَ بِإِذْنِ ٱللَّهِ مُصَدِّقًا لِّمَا بَيْنَ يَدَيْهِ وَهُدًى وَبُشْرَىٰ لِلْمُؤْمِنِينَ","en":"Say, \"Whoever is an enemy to Gabriel - it is [none but] he who has brought it [i.e., the Qur’ān] down upon your heart, [O Muḥammad], by permission of Allāh, confirming that which was before it and as guidance and good tidings for the believers.\"","tr":"Qul man kana AAaduwwan lijibreelafa-innahu nazzalahu AAala qalbika bi-ithni Allahimusaddiqan lima bayna yadayhi wahudan wabushralilmu/mineen","juz":1,"page":15},{"s":2,"a":98,"key":"2:98","ar":"مَن كَانَ عَدُوًّا لِّلَّهِ وَمَلَـٰٓئِكَتِهِۦ وَرُسُلِهِۦ وَجِبْرِيلَ وَمِيكَىٰلَ فَإِنَّ ٱللَّهَ عَدُوٌّ لِّلْكَـٰفِرِينَ","en":"Whoever is an enemy to Allāh and His angels and His messengers and Gabriel and Michael - then indeed, Allāh is an enemy to the disbelievers.","tr":"Man kana AAaduwwan lillahiwamala-ikatihi warusulihi wajibreela wameekalafa-inna Allaha AAaduwwun lilkafireen","juz":1,"page":15},{"s":2,"a":99,"key":"2:99","ar":"وَلَقَدْ أَنزَلْنَآ إِلَيْكَ ءَايَـٰتٍۭ بَيِّنَـٰتٍ ۖ وَمَا يَكْفُرُ بِهَآ إِلَّا ٱلْفَـٰسِقُونَ","en":"And We have certainly revealed to you verses [which are] clear proofs, and no one would deny them except the defiantly disobedient.","tr":"Walaqad anzalna ilayka ayatinbayyinatin wama yakfuru biha illa alfasiqoon","juz":1,"page":15},{"s":2,"a":100,"key":"2:100","ar":"أَوَكُلَّمَا عَـٰهَدُوا۟ عَهْدًا نَّبَذَهُۥ فَرِيقٌ مِّنْهُم ۚ بَلْ أَكْثَرُهُمْ لَا يُؤْمِنُونَ","en":"Is it not [true] that every time they took a covenant a party of them threw it away? But, [in fact], most of them do not believe.","tr":"Awa kullama AAahadoo AAahdannabathahu fareequn minhum bal aktharuhum layu/minoon","juz":1,"page":15},{"s":2,"a":101,"key":"2:101","ar":"وَلَمَّا جَآءَهُمْ رَسُولٌ مِّنْ عِندِ ٱللَّهِ مُصَدِّقٌ لِّمَا مَعَهُمْ نَبَذَ فَرِيقٌ مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ كِتَـٰبَ ٱللَّهِ وَرَآءَ ظُهُورِهِمْ كَأَنَّهُمْ لَا يَعْلَمُونَ","en":"And when a messenger from Allāh came to them confirming that which was with them, a party of those who had been given the Scripture threw the Scripture of Allāh [i.e., the Torah] behind their backs as if they did not know [what it contained].","tr":"Walamma jaahum rasoolun minAAindi Allahi musaddiqun lima maAAahum nabathafareequn mina allatheena ootoo alkitaba kitabaAllahi waraa thuhoorihim kaannahum layaAAlamoon","juz":1,"page":15},{"s":2,"a":102,"key":"2:102","ar":"وَٱتَّبَعُوا۟ مَا تَتْلُوا۟ ٱلشَّيَـٰطِينُ عَلَىٰ مُلْكِ سُلَيْمَـٰنَ ۖ وَمَا كَفَرَ سُلَيْمَـٰنُ وَلَـٰكِنَّ ٱلشَّيَـٰطِينَ كَفَرُوا۟ يُعَلِّمُونَ ٱلنَّاسَ ٱلسِّحْرَ وَمَآ أُنزِلَ عَلَى ٱلْمَلَكَيْنِ بِبَابِلَ هَـٰرُوتَ وَمَـٰرُوتَ ۚ وَمَا يُعَلِّمَانِ مِنْ أَحَدٍ حَتَّىٰ يَقُولَآ إِنَّمَا نَحْنُ فِتْنَةٌ فَلَا تَكْفُرْ ۖ فَيَتَعَلَّمُونَ مِنْهُمَا مَا يُفَرِّقُونَ بِهِۦ بَيْنَ ٱلْمَرْءِ وَزَوْجِهِۦ ۚ وَمَا هُم بِضَآرِّينَ بِهِۦ مِنْ أَحَدٍ إِلَّا بِإِذْنِ ٱللَّهِ ۚ وَيَتَعَلَّمُونَ مَا يَضُرُّهُمْ وَلَا يَنفَعُهُمْ ۚ وَلَقَدْ عَلِمُوا۟ لَمَنِ ٱشْتَرَىٰهُ مَا لَهُۥ فِى ٱلْـَٔاخِرَةِ مِنْ خَلَـٰقٍ ۚ وَلَبِئْسَ مَا شَرَوْا۟ بِهِۦٓ أَنفُسَهُمْ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ","en":"And they followed [instead] what the devils had recited during the reign of Solomon. It was not Solomon who disbelieved, but the devils disbelieved, teaching people magic and that which was revealed to the two angels at Babylon, Hārūt and Mārūt. But they [i.e., the two angels] do not teach anyone unless they say, \"We are a trial, so do not disbelieve [by practicing magic].\"1 And [yet] they learn from them that by which they cause separation between a man and his wife. But they do not harm anyone through it except by permission of Allāh. And they [i.e., people] learn what harms them and does not benefit them. But they [i.e., the Children of Israel] certainly knew that whoever purchased it [i.e., magic] would not have in the Hereafter any share. And wretched is that for which they sold themselves, if they only knew.","tr":"WattabaAAoo ma tatloo ashshayateenuAAala mulki sulaymana wama kafara sulaymanuwalakinna ashshayateena kafarooyuAAallimoona annasa assihra wamaonzila AAala almalakayni bibabila harootawamaroota wama yuAAallimani min ahadinhatta yaqoola innama nahnufitnatun fala takfur fayataAAallamoona minhuma mayufarriqoona bihi bayna almar-i wazawjihi wama hum bidarreenabihi min ahadin illa bi-ithni AllahiwayataAAallamoona ma yadurruhum walayanfaAAuhum walaqad AAalimoo lamani ishtarahu malahu fee al-akhirati min khalaqin walabi/sa masharaw bihi anfusahum law kanoo yaAAlamoon","juz":1,"page":16},{"s":2,"a":103,"key":"2:103","ar":"وَلَوْ أَنَّهُمْ ءَامَنُوا۟ وَٱتَّقَوْا۟ لَمَثُوبَةٌ مِّنْ عِندِ ٱللَّهِ خَيْرٌ ۖ لَّوْ كَانُوا۟ يَعْلَمُونَ","en":"And if they had believed and feared Allāh, then the reward from Allāh would have been [far] better, if they only knew.","tr":"Walaw annahum amanoo wattaqawlamathoobatun min AAindi Allahi khayrun law kanooyaAAlamoon","juz":1,"page":16},{"s":2,"a":104,"key":"2:104","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَقُولُوا۟ رَٰعِنَا وَقُولُوا۟ ٱنظُرْنَا وَٱسْمَعُوا۟ ۗ وَلِلْكَـٰفِرِينَ عَذَابٌ أَلِيمٌ","en":"O you who have believed, say not [to Allāh's Messenger], \"Rāʿinā\" but say, \"Unẓurnā\"1 and listen. And for the disbelievers is a painful punishment.","tr":"Ya ayyuha allatheena amanoola taqooloo raAAina waqooloo onthurnawasmaAAoo walilkafireena AAathabun aleem","juz":1,"page":16},{"s":2,"a":105,"key":"2:105","ar":"مَّا يَوَدُّ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَـٰبِ وَلَا ٱلْمُشْرِكِينَ أَن يُنَزَّلَ عَلَيْكُم مِّنْ خَيْرٍ مِّن رَّبِّكُمْ ۗ وَٱللَّهُ يَخْتَصُّ بِرَحْمَتِهِۦ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ","en":"Neither those who disbelieve from the People of the Scripture [i.e., the Jews and Christians] nor the polytheists wish that any good should be sent down to you from your Lord. But Allāh selects for His mercy whom He wills, and Allāh is the possessor of great bounty.","tr":"Ma yawaddu allatheena kafaroomin ahli alkitabi wala almushrikeena an yunazzalaAAalaykum min khayrin min rabbikum wallahu yakhtassubirahmatihi man yashao wallahu thooalfadli alAAatheem","juz":1,"page":16},{"s":2,"a":106,"key":"2:106","ar":"۞ مَا نَنسَخْ مِنْ ءَايَةٍ أَوْ نُنسِهَا نَأْتِ بِخَيْرٍ مِّنْهَآ أَوْ مِثْلِهَآ ۗ أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"We do not abrogate a verse or cause it to be forgotten except that We bring forth [one] better than it or similar to it. Do you not know that Allāh is over all things competent?","tr":"Ma nansakh min ayatin awnunsiha na/ti bikhayrin minha aw mithlihaalam taAAlam anna Allaha AAala kulli shay-in qadeer","juz":1,"page":17},{"s":2,"a":107,"key":"2:107","ar":"أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ لَهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۗ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّ وَلَا نَصِيرٍ","en":"Do you not know that to Allāh belongs the dominion of the heavens and the earth and [that] you have not besides Allāh any protector or any helper?","tr":"Alam taAAlam anna Allaha lahu mulkuassamawati wal-ardi wamalakum min dooni Allahi min waliyyin wala naseer","juz":1,"page":17},{"s":2,"a":108,"key":"2:108","ar":"أَمْ تُرِيدُونَ أَن تَسْـَٔلُوا۟ رَسُولَكُمْ كَمَا سُئِلَ مُوسَىٰ مِن قَبْلُ ۗ وَمَن يَتَبَدَّلِ ٱلْكُفْرَ بِٱلْإِيمَـٰنِ فَقَدْ ضَلَّ سَوَآءَ ٱلسَّبِيلِ","en":"Or do you intend to ask1 your Messenger as Moses was asked before? And whoever exchanges faith for disbelief has certainly strayed from the soundness of the way.","tr":"Am tureedoona an tas-aloo rasoolakum kamasu-ila moosa min qablu waman yatabaddali alkufra bil-eemanifaqad dalla sawaa assabeel","juz":1,"page":17},{"s":2,"a":109,"key":"2:109","ar":"وَدَّ كَثِيرٌ مِّنْ أَهْلِ ٱلْكِتَـٰبِ لَوْ يَرُدُّونَكُم مِّنۢ بَعْدِ إِيمَـٰنِكُمْ كُفَّارًا حَسَدًا مِّنْ عِندِ أَنفُسِهِم مِّنۢ بَعْدِ مَا تَبَيَّنَ لَهُمُ ٱلْحَقُّ ۖ فَٱعْفُوا۟ وَٱصْفَحُوا۟ حَتَّىٰ يَأْتِىَ ٱللَّهُ بِأَمْرِهِۦٓ ۗ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Many of the People of the Scripture wish they could turn you back to disbelief after you have believed, out of envy from themselves [even] after the truth has become clear to them. So pardon and overlook until Allāh delivers His command. Indeed, Allāh is over all things competent.","tr":"Wadda katheerun min ahli alkitabilaw yaruddoonakum min baAAdi eemanikum kuffaran hasadanmin AAindi anfusihim min baAAdi ma tabayyana lahumu alhaqqufaAAfoo wasfahoo hattaya/tiya Allahu bi-amrihi inna Allaha AAalakulli shay-in qadeer","juz":1,"page":17},{"s":2,"a":110,"key":"2:110","ar":"وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ ۚ وَمَا تُقَدِّمُوا۟ لِأَنفُسِكُم مِّنْ خَيْرٍ تَجِدُوهُ عِندَ ٱللَّهِ ۗ إِنَّ ٱللَّهَ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"And establish prayer and give zakāh, and whatever good you put forward for yourselves - you will find it with Allāh. Indeed Allāh, of what you do, is Seeing.","tr":"Waaqeemoo assalata waatooazzakata wama tuqaddimoo li-anfusikum minkhayrin tajidoohu AAinda Allahi inna Allaha bimataAAmaloona baseer","juz":1,"page":17},{"s":2,"a":111,"key":"2:111","ar":"وَقَالُوا۟ لَن يَدْخُلَ ٱلْجَنَّةَ إِلَّا مَن كَانَ هُودًا أَوْ نَصَـٰرَىٰ ۗ تِلْكَ أَمَانِيُّهُمْ ۗ قُلْ هَاتُوا۟ بُرْهَـٰنَكُمْ إِن كُنتُمْ صَـٰدِقِينَ","en":"And they say, \"None will enter Paradise except one who is a Jew or a Christian.\" That is [merely] their wishful thinking. Say, \"Produce your proof, if you should be truthful.\"","tr":"Waqaloo lan yadkhula aljannata illaman kana hoodan aw nasara tilka amaniyyuhumqul hatoo burhanakum in kuntum sadiqeen","juz":1,"page":17},{"s":2,"a":112,"key":"2:112","ar":"بَلَىٰ مَنْ أَسْلَمَ وَجْهَهُۥ لِلَّهِ وَهُوَ مُحْسِنٌ فَلَهُۥٓ أَجْرُهُۥ عِندَ رَبِّهِۦ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"Yes, [on the contrary], whoever submits his face [i.e., self] in Islām to Allāh while being a doer of good will have his reward with his Lord. And no fear will there be concerning them, nor will they grieve.","tr":"Bala man aslama wajhahu lillahiwahuwa muhsinun falahu ajruhu AAinda rabbihi walakhawfun AAalayhim wala hum yahzanoon","juz":1,"page":17},{"s":2,"a":113,"key":"2:113","ar":"وَقَالَتِ ٱلْيَهُودُ لَيْسَتِ ٱلنَّصَـٰرَىٰ عَلَىٰ شَىْءٍ وَقَالَتِ ٱلنَّصَـٰرَىٰ لَيْسَتِ ٱلْيَهُودُ عَلَىٰ شَىْءٍ وَهُمْ يَتْلُونَ ٱلْكِتَـٰبَ ۗ كَذَٰلِكَ قَالَ ٱلَّذِينَ لَا يَعْلَمُونَ مِثْلَ قَوْلِهِمْ ۚ فَٱللَّهُ يَحْكُمُ بَيْنَهُمْ يَوْمَ ٱلْقِيَـٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ","en":"The Jews say, \"The Christians have nothing [true] to stand on,\" and the Christians say, \"The Jews have nothing to stand on,\" although they [both] recite the Scripture. Thus do those who know not [i.e., the polytheists] speak the same as their words. But Allāh will judge between them on the Day of Resurrection concerning that over which they used to differ.","tr":"Waqalati alyahoodu laysati annasaraAAala shay-in waqalati annasaralaysati alyahoodu AAala shay-in wahum yatloona alkitabakathalika qala allatheena layaAAlamoona mithla qawlihim fallahu yahkumubaynahum yawma alqiyamati feema kanoo feehiyakhtalifoon","juz":1,"page":18},{"s":2,"a":114,"key":"2:114","ar":"وَمَنْ أَظْلَمُ مِمَّن مَّنَعَ مَسَـٰجِدَ ٱللَّهِ أَن يُذْكَرَ فِيهَا ٱسْمُهُۥ وَسَعَىٰ فِى خَرَابِهَآ ۚ أُو۟لَـٰٓئِكَ مَا كَانَ لَهُمْ أَن يَدْخُلُوهَآ إِلَّا خَآئِفِينَ ۚ لَهُمْ فِى ٱلدُّنْيَا خِزْىٌ وَلَهُمْ فِى ٱلْـَٔاخِرَةِ عَذَابٌ عَظِيمٌ","en":"And who are more unjust than those who prevent the name of Allāh from being mentioned [i.e., praised] in His mosques and strive toward their destruction. It is not for them to enter them except in fear. For them in this world is disgrace, and they will have in the Hereafter a great punishment.","tr":"Waman athlamu mimman manaAAamasajida Allahi an yuthkara feehaismuhu wasaAAa fee kharabiha ola-ikama kana lahum an yadkhulooha illa kha-ifeenalahum fee addunya khizyun walahum fee al-akhiratiAAathabun AAatheem","juz":1,"page":18},{"s":2,"a":115,"key":"2:115","ar":"وَلِلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ فَأَيْنَمَا تُوَلُّوا۟ فَثَمَّ وَجْهُ ٱللَّهِ ۚ إِنَّ ٱللَّهَ وَٰسِعٌ عَلِيمٌ","en":"And to Allāh belongs the east and the west. So wherever you [might] turn, there is the Face1 of Allāh. Indeed, Allāh is all-Encompassing and Knowing.","tr":"Walillahi almashriqu walmaghribufaaynama tuwalloo fathamma wajhu Allahi inna AllahawasiAAun AAaleem","juz":1,"page":18},{"s":2,"a":116,"key":"2:116","ar":"وَقَالُوا۟ ٱتَّخَذَ ٱللَّهُ وَلَدًا ۗ سُبْحَـٰنَهُۥ ۖ بَل لَّهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ كُلٌّ لَّهُۥ قَـٰنِتُونَ","en":"They say, \"Allāh has taken a son.\" Exalted is He!1 Rather, to Him belongs whatever is in the heavens and the earth. All are devoutly obedient to Him,","tr":"Waqaloo itakhatha Allahuwaladan subhanahu bal lahu ma fee assamawatiwal-ardi kullun lahu qanitoon","juz":1,"page":18},{"s":2,"a":117,"key":"2:117","ar":"بَدِيعُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ وَإِذَا قَضَىٰٓ أَمْرًا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ","en":"Originator of the heavens and the earth. When He decrees a matter, He only says to it, \"Be,\" and it is.","tr":"BadeeAAu assamawatiwal-ardi wa-itha qada amran fa-innamayaqoolu lahu kun fayakoon","juz":1,"page":18},{"s":2,"a":118,"key":"2:118","ar":"وَقَالَ ٱلَّذِينَ لَا يَعْلَمُونَ لَوْلَا يُكَلِّمُنَا ٱللَّهُ أَوْ تَأْتِينَآ ءَايَةٌ ۗ كَذَٰلِكَ قَالَ ٱلَّذِينَ مِن قَبْلِهِم مِّثْلَ قَوْلِهِمْ ۘ تَشَـٰبَهَتْ قُلُوبُهُمْ ۗ قَدْ بَيَّنَّا ٱلْـَٔايَـٰتِ لِقَوْمٍ يُوقِنُونَ","en":"Those who do not know say, \"Why does Allāh not speak to us or there come to us a sign?\" Thus spoke those before them like their words. Their hearts resemble each other. We have shown clearly the signs to a people who are certain [in faith].","tr":"Waqala allatheena layaAAlamoona lawla yukallimuna Allahu awta/teena ayatun kathalika qala allatheenamin qablihim mithla qawlihim tashabahat quloobuhum qadbayyanna al-ayati liqawmin yooqinoon","juz":1,"page":18},{"s":2,"a":119,"key":"2:119","ar":"إِنَّآ أَرْسَلْنَـٰكَ بِٱلْحَقِّ بَشِيرًا وَنَذِيرًا ۖ وَلَا تُسْـَٔلُ عَنْ أَصْحَـٰبِ ٱلْجَحِيمِ","en":"Indeed, We have sent you, [O Muḥammad], with the truth as a bringer of good tidings and a warner, and you will not be asked about the companions of Hellfire.","tr":"Inna arsalnaka bilhaqqibasheeran wanatheeran wala tus-alu Aaan as-habialjaheem","juz":1,"page":18},{"s":2,"a":120,"key":"2:120","ar":"وَلَن تَرْضَىٰ عَنكَ ٱلْيَهُودُ وَلَا ٱلنَّصَـٰرَىٰ حَتَّىٰ تَتَّبِعَ مِلَّتَهُمْ ۗ قُلْ إِنَّ هُدَى ٱللَّهِ هُوَ ٱلْهُدَىٰ ۗ وَلَئِنِ ٱتَّبَعْتَ أَهْوَآءَهُم بَعْدَ ٱلَّذِى جَآءَكَ مِنَ ٱلْعِلْمِ ۙ مَا لَكَ مِنَ ٱللَّهِ مِن وَلِىٍّ وَلَا نَصِيرٍ","en":"And never will the Jews and the Christians approve of you until you follow their religion. Say, \"Indeed, the guidance of Allāh is the [only] guidance.\" If you were to follow their desires after what has come to you of knowledge, you would have against Allāh no protector or helper.","tr":"Walan tarda AAanka alyahoodu walaannasara hatta tattabiAAamillatahum qul inna huda Allahi huwa alhudawala-ini ittabaAAta ahwaahum baAAda allathee jaakamina alAAilmi ma laka mina Allahi min waliyyin walanaseer","juz":1,"page":19},{"s":2,"a":121,"key":"2:121","ar":"ٱلَّذِينَ ءَاتَيْنَـٰهُمُ ٱلْكِتَـٰبَ يَتْلُونَهُۥ حَقَّ تِلَاوَتِهِۦٓ أُو۟لَـٰٓئِكَ يُؤْمِنُونَ بِهِۦ ۗ وَمَن يَكْفُرْ بِهِۦ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْخَـٰسِرُونَ","en":"Those to whom We have given the Book recite it with its true recital.1 They [are the ones who] believe in it. And whoever disbelieves in it - it is they who are the losers.","tr":"Allatheena ataynahumualkitaba yatloonahu haqqa tilawatihi ola-ikayu/minoona bihi waman yakfur bihi faola-ika humu alkhasiroon","juz":1,"page":19},{"s":2,"a":122,"key":"2:122","ar":"يَـٰبَنِىٓ إِسْرَٰٓءِيلَ ٱذْكُرُوا۟ نِعْمَتِىَ ٱلَّتِىٓ أَنْعَمْتُ عَلَيْكُمْ وَأَنِّى فَضَّلْتُكُمْ عَلَى ٱلْعَـٰلَمِينَ","en":"O Children of Israel, remember My favor which I have bestowed upon you and that I preferred you over the worlds.","tr":"Ya banee isra-eela othkurooniAAmatiya allatee anAAamtu AAalaykum waannee faddaltukumAAala alAAalameen","juz":1,"page":19},{"s":2,"a":123,"key":"2:123","ar":"وَٱتَّقُوا۟ يَوْمًا لَّا تَجْزِى نَفْسٌ عَن نَّفْسٍ شَيْـًٔا وَلَا يُقْبَلُ مِنْهَا عَدْلٌ وَلَا تَنفَعُهَا شَفَـٰعَةٌ وَلَا هُمْ يُنصَرُونَ","en":"And fear a Day when no soul will suffice for another soul1 at all, and no compensation will be accepted from it, nor will any intercession benefit it, nor will they be aided.","tr":"Wattaqoo yawman la tajzeenafsun AAan nafsin shay-an wala yuqbalu minhaAAadlun wala tanfaAAuha shafaAAatun walahum yunsaroon","juz":1,"page":19},{"s":2,"a":124,"key":"2:124","ar":"۞ وَإِذِ ٱبْتَلَىٰٓ إِبْرَٰهِـۧمَ رَبُّهُۥ بِكَلِمَـٰتٍ فَأَتَمَّهُنَّ ۖ قَالَ إِنِّى جَاعِلُكَ لِلنَّاسِ إِمَامًا ۖ قَالَ وَمِن ذُرِّيَّتِى ۖ قَالَ لَا يَنَالُ عَهْدِى ٱلظَّـٰلِمِينَ","en":"And [mention, O Muḥammad], when Abraham was tried by his Lord with words [i.e., commands] and he fulfilled them. [Allāh] said, \"Indeed, I will make you a leader for the people.\" [Abraham] said, \"And of my descendants?\" [Allāh] said, \"My covenant does not include the wrongdoers.\"","tr":"Wa-ithi ibtala ibraheemarabbuhu bikalimatin faatammahunna qala innee jaAAilukalinnasi imaman qala wamin thurriyyateeqala la yanalu AAahdee aththalimeen","juz":1,"page":19},{"s":2,"a":125,"key":"2:125","ar":"وَإِذْ جَعَلْنَا ٱلْبَيْتَ مَثَابَةً لِّلنَّاسِ وَأَمْنًا وَٱتَّخِذُوا۟ مِن مَّقَامِ إِبْرَٰهِـۧمَ مُصَلًّى ۖ وَعَهِدْنَآ إِلَىٰٓ إِبْرَٰهِـۧمَ وَإِسْمَـٰعِيلَ أَن طَهِّرَا بَيْتِىَ لِلطَّآئِفِينَ وَٱلْعَـٰكِفِينَ وَٱلرُّكَّعِ ٱلسُّجُودِ","en":"And [mention] when We made the House [i.e., the Kaʿbah] a place of return for the people and [a place of] security. And take, [O believers], from the standing place of Abraham a place of prayer. And We charged Abraham and Ishmael, [saying], \"Purify My House for those who perform ṭawāf1 and those who are staying [there] for worship and those who bow and prostrate [in prayer].\"","tr":"Wa-ith jaAAalna albayta mathabatanlinnasi waamnan wattakhithoo minmaqami ibraheema musallan waAAahidnaila ibraheema wa-ismaAAeela an tahhirabaytiya litta-ifeena walAAakifeenawarrukkaAAi assujood","juz":1,"page":19},{"s":2,"a":126,"key":"2:126","ar":"وَإِذْ قَالَ إِبْرَٰهِـۧمُ رَبِّ ٱجْعَلْ هَـٰذَا بَلَدًا ءَامِنًا وَٱرْزُقْ أَهْلَهُۥ مِنَ ٱلثَّمَرَٰتِ مَنْ ءَامَنَ مِنْهُم بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ ۖ قَالَ وَمَن كَفَرَ فَأُمَتِّعُهُۥ قَلِيلًا ثُمَّ أَضْطَرُّهُۥٓ إِلَىٰ عَذَابِ ٱلنَّارِ ۖ وَبِئْسَ ٱلْمَصِيرُ","en":"And [mention] when Abraham said, \"My Lord, make this a secure city and provide its people with fruits - whoever of them believes in Allāh and the Last Day.\" [Allāh] said, \"And whoever disbelieves - I will grant him enjoyment for a little; then I will force him to the punishment of the Fire, and wretched is the destination.\"","tr":"Wa-ith qala ibraheemurabbi ijAAal hatha baladan aminan warzuqahlahu mina aththamarati man amana minhumbillahi walyawmi al-akhiri qalawaman kafara faomattiAAuhu qaleelan thumma adtarruhu ilaAAathabi annari wabi/sa almaseer","juz":1,"page":19},{"s":2,"a":127,"key":"2:127","ar":"وَإِذْ يَرْفَعُ إِبْرَٰهِـۧمُ ٱلْقَوَاعِدَ مِنَ ٱلْبَيْتِ وَإِسْمَـٰعِيلُ رَبَّنَا تَقَبَّلْ مِنَّآ ۖ إِنَّكَ أَنتَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"And [mention] when Abraham was raising the foundations of the House and [with him] Ishmael, [saying], \"Our Lord, accept [this] from us. Indeed, You are the Hearing,1 the Knowing.2","tr":"Wa-ith yarfaAAu ibraheemualqawaAAida mina albayti wa-ismaAAeelu rabbanataqabbal minna innaka anta assameeAAu alAAaleem","juz":1,"page":20},{"s":2,"a":128,"key":"2:128","ar":"رَبَّنَا وَٱجْعَلْنَا مُسْلِمَيْنِ لَكَ وَمِن ذُرِّيَّتِنَآ أُمَّةً مُّسْلِمَةً لَّكَ وَأَرِنَا مَنَاسِكَنَا وَتُبْ عَلَيْنَآ ۖ إِنَّكَ أَنتَ ٱلتَّوَّابُ ٱلرَّحِيمُ","en":"Our Lord, and make us Muslims [in submission] to You and from our descendants a Muslim nation [in submission] to You. And show us our rites [of worship] and accept our repentance. Indeed, You are the Accepting of Repentance, the Merciful.","tr":"Rabbana wajAAalnamuslimayni laka wamin thurriyyatina ommatanmuslimatan laka waarina manasikana watubAAalayna innaka anta attawwabu arraheem","juz":1,"page":20},{"s":2,"a":129,"key":"2:129","ar":"رَبَّنَا وَٱبْعَثْ فِيهِمْ رَسُولًا مِّنْهُمْ يَتْلُوا۟ عَلَيْهِمْ ءَايَـٰتِكَ وَيُعَلِّمُهُمُ ٱلْكِتَـٰبَ وَٱلْحِكْمَةَ وَيُزَكِّيهِمْ ۚ إِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Our Lord, and send among them a messenger from themselves who will recite to them Your verses and teach them the Book and wisdom and purify them. Indeed, You are the Exalted in Might,1 the Wise.\"","tr":"Rabbana wabAAath feehimrasoolan minhum yatloo AAalayhim ayatikawayuAAallimuhumu alkitaba walhikmatawayuzakkeehim innaka anta alAAazeezu alhakeem","juz":1,"page":20},{"s":2,"a":130,"key":"2:130","ar":"وَمَن يَرْغَبُ عَن مِّلَّةِ إِبْرَٰهِـۧمَ إِلَّا مَن سَفِهَ نَفْسَهُۥ ۚ وَلَقَدِ ٱصْطَفَيْنَـٰهُ فِى ٱلدُّنْيَا ۖ وَإِنَّهُۥ فِى ٱلْـَٔاخِرَةِ لَمِنَ ٱلصَّـٰلِحِينَ","en":"And who would be averse to the religion of Abraham except one who makes a fool of himself. And We had chosen him in this world, and indeed he, in the Hereafter, will be among the righteous.","tr":"Waman yarghabu AAan millati ibraheemailla man safiha nafsahu walaqadi istafaynahufee addunya wa-innahu fee al-akhiratilamina assaliheen","juz":1,"page":20},{"s":2,"a":131,"key":"2:131","ar":"إِذْ قَالَ لَهُۥ رَبُّهُۥٓ أَسْلِمْ ۖ قَالَ أَسْلَمْتُ لِرَبِّ ٱلْعَـٰلَمِينَ","en":"When his Lord said to him, \"Submit,\" he said, \"I have submitted [in Islām]1 to the Lord of the worlds.\"","tr":"Ith qala lahu rabbuhu aslim qalaaslamtu lirabbi alAAalameen","juz":1,"page":20},{"s":2,"a":132,"key":"2:132","ar":"وَوَصَّىٰ بِهَآ إِبْرَٰهِـۧمُ بَنِيهِ وَيَعْقُوبُ يَـٰبَنِىَّ إِنَّ ٱللَّهَ ٱصْطَفَىٰ لَكُمُ ٱلدِّينَ فَلَا تَمُوتُنَّ إِلَّا وَأَنتُم مُّسْلِمُونَ","en":"And Abraham instructed his sons [to do the same] and [so did] Jacob, [saying], \"O my sons, indeed Allāh has chosen for you this religion, so do not die except while you are Muslims.\"","tr":"Wawassa biha ibraheemubaneehi wayaAAqoobu ya baniyya inna Allaha istafalakumu addeena fala tamootunna illa waantummuslimoon","juz":1,"page":20},{"s":2,"a":133,"key":"2:133","ar":"أَمْ كُنتُمْ شُهَدَآءَ إِذْ حَضَرَ يَعْقُوبَ ٱلْمَوْتُ إِذْ قَالَ لِبَنِيهِ مَا تَعْبُدُونَ مِنۢ بَعْدِى قَالُوا۟ نَعْبُدُ إِلَـٰهَكَ وَإِلَـٰهَ ءَابَآئِكَ إِبْرَٰهِـۧمَ وَإِسْمَـٰعِيلَ وَإِسْحَـٰقَ إِلَـٰهًا وَٰحِدًا وَنَحْنُ لَهُۥ مُسْلِمُونَ","en":"Or were you witnesses when death approached Jacob, when he said to his sons, \"What will you worship after me?\" They said, \"We will worship your God and the God of your fathers, Abraham and Ishmael and Isaac - one God.1 And we are Muslims [in submission] to Him.\"","tr":"Am kuntum shuhadaa ith hadarayaAAqooba almawtu ith qala libaneehi mataAAbudoona min baAAdee qaloo naAAbudu ilahakawa-ilaha aba-ika ibraheema wa-ismaAAeelawa-ishaqa ilahan wahidan wanahnu lahumuslimoon","juz":1,"page":20},{"s":2,"a":134,"key":"2:134","ar":"تِلْكَ أُمَّةٌ قَدْ خَلَتْ ۖ لَهَا مَا كَسَبَتْ وَلَكُم مَّا كَسَبْتُمْ ۖ وَلَا تُسْـَٔلُونَ عَمَّا كَانُوا۟ يَعْمَلُونَ","en":"That was a nation which has passed on. It will have [the consequence of] what it earned, and you will have what you have earned. And you will not be asked about what they used to do.","tr":"Tilka ommatun qad khalat laha makasabat walakum ma kasabtum wala tus-aloona AAammakano yaAAmaloon","juz":1,"page":20},{"s":2,"a":135,"key":"2:135","ar":"وَقَالُوا۟ كُونُوا۟ هُودًا أَوْ نَصَـٰرَىٰ تَهْتَدُوا۟ ۗ قُلْ بَلْ مِلَّةَ إِبْرَٰهِـۧمَ حَنِيفًا ۖ وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ","en":"They say, \"Be Jews or Christians [so] you will be guided.\" Say, \"Rather, [we follow] the religion of Abraham, inclining toward truth, and he was not of the polytheists.\"1","tr":"Waqaloo koonoo hoodan aw nasaratahtadoo qul bal millata ibraheema haneefan wamakana mina almushrikeen","juz":1,"page":21},{"s":2,"a":136,"key":"2:136","ar":"قُولُوٓا۟ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ إِلَيْنَا وَمَآ أُنزِلَ إِلَىٰٓ إِبْرَٰهِـۧمَ وَإِسْمَـٰعِيلَ وَإِسْحَـٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطِ وَمَآ أُوتِىَ مُوسَىٰ وَعِيسَىٰ وَمَآ أُوتِىَ ٱلنَّبِيُّونَ مِن رَّبِّهِمْ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِّنْهُمْ وَنَحْنُ لَهُۥ مُسْلِمُونَ","en":"Say, [O believers], \"We have believed in Allāh and what has been revealed to us and what has been revealed to Abraham and Ishmael and Isaac and Jacob and the Descendants [al-Asbāṭ]1 and what was given to Moses and Jesus and what was given to the prophets from their Lord. We make no distinction between any of them, and we are Muslims [in submission] to Him.\"","tr":"Qooloo amanna billahiwama onzila ilayna wama onzila ilaibraheema wa-ismaAAeela wa-ishaqawayaAAqooba wal-asbati wama ootiya moosawaAAeesa wama ootiya annabiyyoona minrabbihim la nufarriqu bayna ahadin minhum wanahnulahu muslimoon","juz":1,"page":21},{"s":2,"a":137,"key":"2:137","ar":"فَإِنْ ءَامَنُوا۟ بِمِثْلِ مَآ ءَامَنتُم بِهِۦ فَقَدِ ٱهْتَدَوا۟ ۖ وَّإِن تَوَلَّوْا۟ فَإِنَّمَا هُمْ فِى شِقَاقٍ ۖ فَسَيَكْفِيكَهُمُ ٱللَّهُ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"So if they believe in the same as you believe in, then they have been [rightly] guided; but if they turn away, they are only in dissension, and Allāh will be sufficient for you against them. And He is the Hearing, the Knowing.","tr":"Fa-in amanoo bimithli ma amantumbihi faqadi ihtadaw wa-in tawallaw fa-innama hum fee shiqaqinfasayakfeekahumu Allahu wahuwa assameeAAualAAaleem","juz":1,"page":21},{"s":2,"a":138,"key":"2:138","ar":"صِبْغَةَ ٱللَّهِ ۖ وَمَنْ أَحْسَنُ مِنَ ٱللَّهِ صِبْغَةً ۖ وَنَحْنُ لَهُۥ عَـٰبِدُونَ","en":"[And say, \"Ours is] the religion of Allāh. And who is better than Allāh in [ordaining] religion? And we are worshippers of Him.\"","tr":"Sibghata Allahi waman ahsanumina Allahi sibghatan wanahnu lahu AAabidoon","juz":1,"page":21},{"s":2,"a":139,"key":"2:139","ar":"قُلْ أَتُحَآجُّونَنَا فِى ٱللَّهِ وَهُوَ رَبُّنَا وَرَبُّكُمْ وَلَنَآ أَعْمَـٰلُنَا وَلَكُمْ أَعْمَـٰلُكُمْ وَنَحْنُ لَهُۥ مُخْلِصُونَ","en":"Say, [O Muḥammad], \"Do you argue with us about Allāh while He is our Lord and your Lord? For us are our deeds, and for you are your deeds. And we are sincere [in deed and intention] to Him.\"","tr":"Qul atuhajjoonana fee Allahiwahuwa rabbuna warabbukum walana aAAmalunawalakum aAAmalukum wanahnu lahu mukhlisoon","juz":1,"page":21},{"s":2,"a":140,"key":"2:140","ar":"أَمْ تَقُولُونَ إِنَّ إِبْرَٰهِـۧمَ وَإِسْمَـٰعِيلَ وَإِسْحَـٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطَ كَانُوا۟ هُودًا أَوْ نَصَـٰرَىٰ ۗ قُلْ ءَأَنتُمْ أَعْلَمُ أَمِ ٱللَّهُ ۗ وَمَنْ أَظْلَمُ مِمَّن كَتَمَ شَهَـٰدَةً عِندَهُۥ مِنَ ٱللَّهِ ۗ وَمَا ٱللَّهُ بِغَـٰفِلٍ عَمَّا تَعْمَلُونَ","en":"Or do you say that Abraham and Ishmael and Isaac and Jacob and the Descendants were Jews or Christians? Say, \"Are you more knowing or is Allāh?\" And who is more unjust than one who conceals a testimony1 he has from Allāh? And Allāh is not unaware of what you do.","tr":"Am taqooloona inna ibraheema wa-ismaAAeelawa-ishaqa wayaAAqooba wal-asbata kanoohoodan aw nasara qul aantum aAAlamu ami Allahuwaman athlamu mimman katama shahadatanAAindahu mina Allahi wama Allahu bighafilinAAamma taAAmaloon","juz":1,"page":21},{"s":2,"a":141,"key":"2:141","ar":"تِلْكَ أُمَّةٌ قَدْ خَلَتْ ۖ لَهَا مَا كَسَبَتْ وَلَكُم مَّا كَسَبْتُمْ ۖ وَلَا تُسْـَٔلُونَ عَمَّا كَانُوا۟ يَعْمَلُونَ","en":"That is a nation which has passed on. It will have [the consequence of] what it earned, and you will have what you have earned. And you will not be asked about what they used to do.","tr":"Tilka ommatun qad khalat laha makasabat walakum ma kasabtum wala tus-aloona AAammakanoo yaAAmaloon","juz":1,"page":21},{"s":2,"a":142,"key":"2:142","ar":"۞ سَيَقُولُ ٱلسُّفَهَآءُ مِنَ ٱلنَّاسِ مَا وَلَّىٰهُمْ عَن قِبْلَتِهِمُ ٱلَّتِى كَانُوا۟ عَلَيْهَا ۚ قُل لِّلَّهِ ٱلْمَشْرِقُ وَٱلْمَغْرِبُ ۚ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"The foolish among the people will say, \"What has turned them away from their qiblah,1 which they used to face?\"2 Say, \"To Allāh belongs the east and the west. He guides whom He wills to a straight path.\"","tr":"Sayaqoolu assufahao mina annasima wallahum AAan qiblatihimu allatee kanooAAalayha qul lillahi almashriqu walmaghribuyahdee man yashao ila siratinmustaqeem","juz":2,"page":22},{"s":2,"a":143,"key":"2:143","ar":"وَكَذَٰلِكَ جَعَلْنَـٰكُمْ أُمَّةً وَسَطًا لِّتَكُونُوا۟ شُهَدَآءَ عَلَى ٱلنَّاسِ وَيَكُونَ ٱلرَّسُولُ عَلَيْكُمْ شَهِيدًا ۗ وَمَا جَعَلْنَا ٱلْقِبْلَةَ ٱلَّتِى كُنتَ عَلَيْهَآ إِلَّا لِنَعْلَمَ مَن يَتَّبِعُ ٱلرَّسُولَ مِمَّن يَنقَلِبُ عَلَىٰ عَقِبَيْهِ ۚ وَإِن كَانَتْ لَكَبِيرَةً إِلَّا عَلَى ٱلَّذِينَ هَدَى ٱللَّهُ ۗ وَمَا كَانَ ٱللَّهُ لِيُضِيعَ إِيمَـٰنَكُمْ ۚ إِنَّ ٱللَّهَ بِٱلنَّاسِ لَرَءُوفٌ رَّحِيمٌ","en":"And thus We have made you a median [i.e., just] community that you will be witnesses over the people and the Messenger will be a witness over you. And We did not make the qiblah which you used to face except that We might make evident who would follow the Messenger from who would turn back on his heels.1 And indeed, it is difficult except for those whom Allāh has guided. And never would Allāh have caused you to lose your faith [i.e., your previous prayers]. Indeed Allāh is, to the people, Kind and Merciful.","tr":"Wakathalika jaAAalnakumommatan wasatan litakoonoo shuhadaa AAala annasiwayakoona arrasoolu AAalaykum shaheedan wamajaAAalna alqiblata allatee kunta AAalayha illalinaAAlama man yattabiAAu arrasoola mimman yanqalibu AAalaAAaqibayhi wa-in kanat lakabeeratan illa AAalaallatheena hada Allahu wama kanaAllahu liyudeeAAa eemanakum inna Allahabinnasi laraoofun raheem","juz":2,"page":22},{"s":2,"a":144,"key":"2:144","ar":"قَدْ نَرَىٰ تَقَلُّبَ وَجْهِكَ فِى ٱلسَّمَآءِ ۖ فَلَنُوَلِّيَنَّكَ قِبْلَةً تَرْضَىٰهَا ۚ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ وَحَيْثُ مَا كُنتُمْ فَوَلُّوا۟ وُجُوهَكُمْ شَطْرَهُۥ ۗ وَإِنَّ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ لَيَعْلَمُونَ أَنَّهُ ٱلْحَقُّ مِن رَّبِّهِمْ ۗ وَمَا ٱللَّهُ بِغَـٰفِلٍ عَمَّا يَعْمَلُونَ","en":"We have certainly seen the turning of your face, [O Muḥammad], toward the heaven, and We will surely turn you to a qiblah with which you will be pleased. So turn your face [i.e., yourself] toward al-Masjid al-Ḥarām.1 And wherever you [believers] are, turn your faces [i.e., yourselves] toward it [in prayer]. Indeed, those who have been given the Scripture [i.e., the Jews and the Christians] well know that it is the truth from their Lord. And Allāh is not unaware of what they do.","tr":"Qad nara taqalluba wajhika fee assama-ifalanuwalliyannaka qiblatan tardaha fawalli wajhakashatra almasjidi alharami wahaythu makuntum fawalloo wujoohakum shatrahu wa-inna allatheenaootoo alkitaba layaAAlamoona annahu alhaqqu minrabbihim wama Allahu bighafilin AAammayaAAmaloon","juz":2,"page":22},{"s":2,"a":145,"key":"2:145","ar":"وَلَئِنْ أَتَيْتَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ بِكُلِّ ءَايَةٍ مَّا تَبِعُوا۟ قِبْلَتَكَ ۚ وَمَآ أَنتَ بِتَابِعٍ قِبْلَتَهُمْ ۚ وَمَا بَعْضُهُم بِتَابِعٍ قِبْلَةَ بَعْضٍ ۚ وَلَئِنِ ٱتَّبَعْتَ أَهْوَآءَهُم مِّنۢ بَعْدِ مَا جَآءَكَ مِنَ ٱلْعِلْمِ ۙ إِنَّكَ إِذًا لَّمِنَ ٱلظَّـٰلِمِينَ","en":"And if you brought to those who were given the Scripture every sign, they would not follow your qiblah. Nor will you be a follower of their qiblah. Nor would they be followers of one another's qiblah. So if you were to follow their desires after what has come to you of knowledge, indeed, you would then be among the wrongdoers.","tr":"Wala-in atayta allatheena ootooalkitaba bikulli ayatin ma tabiAAooqiblataka wama anta bitabiAAin qiblatahum wamabaAAduhum bitabiAAin qiblata baAAdinwala-ini ittabaAAta ahwaahum min baAAdi ma jaakamina alAAilmi innaka ithan lamina aththalimeen","juz":2,"page":22},{"s":2,"a":146,"key":"2:146","ar":"ٱلَّذِينَ ءَاتَيْنَـٰهُمُ ٱلْكِتَـٰبَ يَعْرِفُونَهُۥ كَمَا يَعْرِفُونَ أَبْنَآءَهُمْ ۖ وَإِنَّ فَرِيقًا مِّنْهُمْ لَيَكْتُمُونَ ٱلْحَقَّ وَهُمْ يَعْلَمُونَ","en":"Those to whom We gave the Scripture know him [i.e., Prophet Muḥammad (ﷺ)] as they know their own sons. But indeed, a party of them conceal the truth while they know [it].","tr":"Allatheena ataynahumualkitaba yaAArifoonahu kama yaAArifoona abnaahumwa-inna fareeqan minhum layaktumoona alhaqqa wahumyaAAlamoon","juz":2,"page":23},{"s":2,"a":147,"key":"2:147","ar":"ٱلْحَقُّ مِن رَّبِّكَ ۖ فَلَا تَكُونَنَّ مِنَ ٱلْمُمْتَرِينَ","en":"The truth is from your Lord, so never be among the doubters.","tr":"Alhaqqu min rabbika falatakoonanna mina almumtareen","juz":2,"page":23},{"s":2,"a":148,"key":"2:148","ar":"وَلِكُلٍّ وِجْهَةٌ هُوَ مُوَلِّيهَا ۖ فَٱسْتَبِقُوا۟ ٱلْخَيْرَٰتِ ۚ أَيْنَ مَا تَكُونُوا۟ يَأْتِ بِكُمُ ٱللَّهُ جَمِيعًا ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"For each [religious following] is a [prayer] direction toward which it faces. So race to [all that is] good. Wherever you may be, Allāh will bring you forth [for judgement] all together. Indeed, Allāh is over all things competent.","tr":"Walikullin wijhatun huwa muwalleehafastabiqoo alkhayrati aynama takoonoo ya/tibikumu Allahu jameeAAan inna Allaha AAalakulli shay-in qadeer","juz":2,"page":23},{"s":2,"a":149,"key":"2:149","ar":"وَمِنْ حَيْثُ خَرَجْتَ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۖ وَإِنَّهُۥ لَلْحَقُّ مِن رَّبِّكَ ۗ وَمَا ٱللَّهُ بِغَـٰفِلٍ عَمَّا تَعْمَلُونَ","en":"So from wherever you go out [for prayer, O Muḥammad], turn your face toward al-Masjid al-Ḥarām, and indeed, it is the truth from your Lord. And Allāh is not unaware of what you do.","tr":"Wamin haythu kharajta fawalliwajhaka shatra almasjidi alharami wa-innahulalhaqqu min rabbika wama Allahu bighafilinAAamma taAAmaloon","juz":2,"page":23},{"s":2,"a":150,"key":"2:150","ar":"وَمِنْ حَيْثُ خَرَجْتَ فَوَلِّ وَجْهَكَ شَطْرَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ وَحَيْثُ مَا كُنتُمْ فَوَلُّوا۟ وُجُوهَكُمْ شَطْرَهُۥ لِئَلَّا يَكُونَ لِلنَّاسِ عَلَيْكُمْ حُجَّةٌ إِلَّا ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ فَلَا تَخْشَوْهُمْ وَٱخْشَوْنِى وَلِأُتِمَّ نِعْمَتِى عَلَيْكُمْ وَلَعَلَّكُمْ تَهْتَدُونَ","en":"And from wherever you go out [for prayer], turn your face toward al-Masjid al-Ḥarām. And wherever you [believers] may be, turn your faces toward it in order that the people will not have any argument against you, except for those of them who commit wrong; so fear them not but fear Me. And [it is] so I may complete My favor upon you and that you may be guided,","tr":"Wamin haythu kharajta fawalliwajhaka shatra almasjidi alharami wahaythuma kuntum fawalloo wujoohakum shatrahu li-allayakoona linnasi AAalaykum hujjatun illaallatheena thalamoo minhum falatakhshawhum wakhshawnee wali-otimma niAAmatee AAalaykumwalaAAallakum tahtadoon","juz":2,"page":23},{"s":2,"a":151,"key":"2:151","ar":"كَمَآ أَرْسَلْنَا فِيكُمْ رَسُولًا مِّنكُمْ يَتْلُوا۟ عَلَيْكُمْ ءَايَـٰتِنَا وَيُزَكِّيكُمْ وَيُعَلِّمُكُمُ ٱلْكِتَـٰبَ وَٱلْحِكْمَةَ وَيُعَلِّمُكُم مَّا لَمْ تَكُونُوا۟ تَعْلَمُونَ","en":"Just as We have sent among you a messenger from yourselves reciting to you Our verses and purifying you and teaching you the Book and wisdom1 and teaching you that which you did not know.","tr":"Kama arsalna feekum rasoolanminkum yatloo AAalaykum ayatinawayuzakkeekum wayuAAallimukumu alkitaba walhikmatawayuAAallimukum ma lam takoonoo taAAlamoon","juz":2,"page":23},{"s":2,"a":152,"key":"2:152","ar":"فَٱذْكُرُونِىٓ أَذْكُرْكُمْ وَٱشْكُرُوا۟ لِى وَلَا تَكْفُرُونِ","en":"So remember Me; I will remember you. And be grateful to Me and do not deny Me.","tr":"Fathkuroonee athkurkumwashkuroo lee wala takfuroon","juz":2,"page":23},{"s":2,"a":153,"key":"2:153","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱسْتَعِينُوا۟ بِٱلصَّبْرِ وَٱلصَّلَوٰةِ ۚ إِنَّ ٱللَّهَ مَعَ ٱلصَّـٰبِرِينَ","en":"O you who have believed, seek help through patience and prayer. Indeed, Allāh is with the patient.","tr":"Ya ayyuha allatheena amanooistaAAeenoo bissabri wassalatiinna Allaha maAAa assabireen","juz":2,"page":23},{"s":2,"a":154,"key":"2:154","ar":"وَلَا تَقُولُوا۟ لِمَن يُقْتَلُ فِى سَبِيلِ ٱللَّهِ أَمْوَٰتٌۢ ۚ بَلْ أَحْيَآءٌ وَلَـٰكِن لَّا تَشْعُرُونَ","en":"And do not say about those who are killed in the way of Allāh, \"They are dead.\" Rather, they are alive, but you perceive [it] not.","tr":"Wala taqooloo liman yuqtalu feesabeeli Allahi amwatun bal ahyaon walakinla tashAAuroon","juz":2,"page":24},{"s":2,"a":155,"key":"2:155","ar":"وَلَنَبْلُوَنَّكُم بِشَىْءٍ مِّنَ ٱلْخَوْفِ وَٱلْجُوعِ وَنَقْصٍ مِّنَ ٱلْأَمْوَٰلِ وَٱلْأَنفُسِ وَٱلثَّمَرَٰتِ ۗ وَبَشِّرِ ٱلصَّـٰبِرِينَ","en":"And We will surely test you with something of fear and hunger and a loss of wealth and lives and fruits, but give good tidings to the patient,","tr":"Walanabluwannakum bishay-in mina alkhawfiwaljooAAi wanaqsin mina al-amwali wal-anfusiwaththamarati wabashshiri assabireen","juz":2,"page":24},{"s":2,"a":156,"key":"2:156","ar":"ٱلَّذِينَ إِذَآ أَصَـٰبَتْهُم مُّصِيبَةٌ قَالُوٓا۟ إِنَّا لِلَّهِ وَإِنَّآ إِلَيْهِ رَٰجِعُونَ","en":"Who, when disaster strikes them, say, \"Indeed we belong to Allāh, and indeed to Him we will return.\"","tr":"Allatheena itha asabat-hummuseebatun qaloo inna lillahi wa-innailayhi rajiAAoon","juz":2,"page":24},{"s":2,"a":157,"key":"2:157","ar":"أُو۟لَـٰٓئِكَ عَلَيْهِمْ صَلَوَٰتٌ مِّن رَّبِّهِمْ وَرَحْمَةٌ ۖ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُهْتَدُونَ","en":"Those are the ones upon whom are blessings from their Lord and mercy. And it is those who are the [rightly] guided.","tr":"Ola-ika AAalayhim salawatunmin rabbihim warahmatun waola-ika humu almuhtadoon","juz":2,"page":24},{"s":2,"a":158,"key":"2:158","ar":"۞ إِنَّ ٱلصَّفَا وَٱلْمَرْوَةَ مِن شَعَآئِرِ ٱللَّهِ ۖ فَمَنْ حَجَّ ٱلْبَيْتَ أَوِ ٱعْتَمَرَ فَلَا جُنَاحَ عَلَيْهِ أَن يَطَّوَّفَ بِهِمَا ۚ وَمَن تَطَوَّعَ خَيْرًا فَإِنَّ ٱللَّهَ شَاكِرٌ عَلِيمٌ","en":"Indeed, aṣ-Ṣafā and al-Marwah are among the symbols1 of Allāh. So whoever makes ḥajj [pilgrimage] to the House or performs ʿumrah - there is no blame upon him for walking between them.2 And whoever volunteers good - then indeed, Allāh is Appreciative3 and Knowing.","tr":"Inna assafa walmarwatamin shaAAa-iri Allahi faman hajja albaytaawi iAAtamara fala junaha AAalayhi an yattawwafabihima waman tatawwaAAa khayran fa-inna Allahashakirun AAaleem","juz":2,"page":24},{"s":2,"a":159,"key":"2:159","ar":"إِنَّ ٱلَّذِينَ يَكْتُمُونَ مَآ أَنزَلْنَا مِنَ ٱلْبَيِّنَـٰتِ وَٱلْهُدَىٰ مِنۢ بَعْدِ مَا بَيَّنَّـٰهُ لِلنَّاسِ فِى ٱلْكِتَـٰبِ ۙ أُو۟لَـٰٓئِكَ يَلْعَنُهُمُ ٱللَّهُ وَيَلْعَنُهُمُ ٱللَّـٰعِنُونَ","en":"Indeed, those who conceal what We sent down of clear proofs and guidance after We made it clear for the people in the Scripture - those are cursed by Allāh and cursed by those who curse,1","tr":"Inna allatheena yaktumoona maanzalna mina albayyinati walhuda minbaAAdi ma bayyannahu linnasi feealkitabi ola-ika yalAAanuhumu AllahuwayalAAanuhumu allaAAinoon","juz":2,"page":24},{"s":2,"a":160,"key":"2:160","ar":"إِلَّا ٱلَّذِينَ تَابُوا۟ وَأَصْلَحُوا۟ وَبَيَّنُوا۟ فَأُو۟لَـٰٓئِكَ أَتُوبُ عَلَيْهِمْ ۚ وَأَنَا ٱلتَّوَّابُ ٱلرَّحِيمُ","en":"Except for those who repent and correct themselves and make evident [what they concealed]. Those - I will accept their repentance, and I am the Accepting of Repentance,1 the Merciful.","tr":"Illa allatheena taboowaaslahoo wabayyanoo faola-ika atoobuAAalayhim waana attawwabu arraheem","juz":2,"page":24},{"s":2,"a":161,"key":"2:161","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَمَاتُوا۟ وَهُمْ كُفَّارٌ أُو۟لَـٰٓئِكَ عَلَيْهِمْ لَعْنَةُ ٱللَّهِ وَٱلْمَلَـٰٓئِكَةِ وَٱلنَّاسِ أَجْمَعِينَ","en":"Indeed, those who disbelieve and die while they are disbelievers - upon them will be the curse of Allāh and of the angels and the people, all together,","tr":"Inna allatheena kafaroo wamatoowahum kuffarun ola-ika AAalayhim laAAnatu Allahiwalmala-ikati wannasi ajmaAAeen","juz":2,"page":24},{"s":2,"a":162,"key":"2:162","ar":"خَـٰلِدِينَ فِيهَا ۖ لَا يُخَفَّفُ عَنْهُمُ ٱلْعَذَابُ وَلَا هُمْ يُنظَرُونَ","en":"Abiding eternally therein. The punishment will not be lightened for them, nor will they be reprieved.","tr":"Khalideena feeha layukhaffafu AAanhumu alAAathabu wala hum yuntharoon","juz":2,"page":24},{"s":2,"a":163,"key":"2:163","ar":"وَإِلَـٰهُكُمْ إِلَـٰهٌ وَٰحِدٌ ۖ لَّآ إِلَـٰهَ إِلَّا هُوَ ٱلرَّحْمَـٰنُ ٱلرَّحِيمُ","en":"And your god is one God. There is no deity [worthy of worship] except Him, the Entirely Merciful, the Especially Merciful.","tr":"Wa-ilahukum ilahun wahidunla ilaha illa huwa arrahmanuarraheem","juz":2,"page":24},{"s":2,"a":164,"key":"2:164","ar":"إِنَّ فِى خَلْقِ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَٱخْتِلَـٰفِ ٱلَّيْلِ وَٱلنَّهَارِ وَٱلْفُلْكِ ٱلَّتِى تَجْرِى فِى ٱلْبَحْرِ بِمَا يَنفَعُ ٱلنَّاسَ وَمَآ أَنزَلَ ٱللَّهُ مِنَ ٱلسَّمَآءِ مِن مَّآءٍ فَأَحْيَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا وَبَثَّ فِيهَا مِن كُلِّ دَآبَّةٍ وَتَصْرِيفِ ٱلرِّيَـٰحِ وَٱلسَّحَابِ ٱلْمُسَخَّرِ بَيْنَ ٱلسَّمَآءِ وَٱلْأَرْضِ لَـَٔايَـٰتٍ لِّقَوْمٍ يَعْقِلُونَ","en":"Indeed, in the creation of the heavens and the earth, and the alternation of the night and the day, and the [great] ships which sail through the sea with that which benefits people, and what Allāh has sent down from the heavens of rain, giving life thereby to the earth after its lifelessness and dispersing therein every [kind of] moving creature, and [His] directing of the winds and the clouds controlled between the heaven and earth are signs for a people who use reason.","tr":"Inna fee khalqi assamawatiwal-ardi wakhtilafi allayli wannahariwalfulki allatee tajree fee albahri bimayanfaAAu annasa wama anzala Allahumina assama-i min ma-in faahyabihi al-arda baAAda mawtiha wabaththa feehamin kulli dabbatin watasreefi arriyahiwassahabi almusakhkhari bayna assama-iwal-ardi laayatin liqawminyaAAqiloon","juz":2,"page":25},{"s":2,"a":165,"key":"2:165","ar":"وَمِنَ ٱلنَّاسِ مَن يَتَّخِذُ مِن دُونِ ٱللَّهِ أَندَادًا يُحِبُّونَهُمْ كَحُبِّ ٱللَّهِ ۖ وَٱلَّذِينَ ءَامَنُوٓا۟ أَشَدُّ حُبًّا لِّلَّهِ ۗ وَلَوْ يَرَى ٱلَّذِينَ ظَلَمُوٓا۟ إِذْ يَرَوْنَ ٱلْعَذَابَ أَنَّ ٱلْقُوَّةَ لِلَّهِ جَمِيعًا وَأَنَّ ٱللَّهَ شَدِيدُ ٱلْعَذَابِ","en":"And [yet], among the people are those who take other than Allāh as equals [to Him]. They love them as they [should] love Allāh. But those who believe are stronger in love for Allāh. And if only they who have wronged would consider [that] when they see the punishment, [they will be certain] that all power belongs to Allāh and that Allāh is severe in punishment.","tr":"Wamina annasi man yattakhithumin dooni Allahi andadan yuhibboonahum kahubbiAllahi wallatheena amanoo ashaddu hubbanlillahi walaw yara allatheena thalamooith yarawna alAAathaba anna alquwwata lillahijameeAAan waanna Allaha shadeedu alAAathab","juz":2,"page":25},{"s":2,"a":166,"key":"2:166","ar":"إِذْ تَبَرَّأَ ٱلَّذِينَ ٱتُّبِعُوا۟ مِنَ ٱلَّذِينَ ٱتَّبَعُوا۟ وَرَأَوُا۟ ٱلْعَذَابَ وَتَقَطَّعَتْ بِهِمُ ٱلْأَسْبَابُ","en":"[And they should consider that] when those who have been followed disassociate themselves from those who followed [them], and they [all] see the punishment, and cut off from them are the ties [of relationship],","tr":"Ith tabarraa allatheenaittubiAAoo mina allatheena ittabaAAoo waraawoo alAAathabawataqattaAAat bihimu al-asbab","juz":2,"page":25},{"s":2,"a":167,"key":"2:167","ar":"وَقَالَ ٱلَّذِينَ ٱتَّبَعُوا۟ لَوْ أَنَّ لَنَا كَرَّةً فَنَتَبَرَّأَ مِنْهُمْ كَمَا تَبَرَّءُوا۟ مِنَّا ۗ كَذَٰلِكَ يُرِيهِمُ ٱللَّهُ أَعْمَـٰلَهُمْ حَسَرَٰتٍ عَلَيْهِمْ ۖ وَمَا هُم بِخَـٰرِجِينَ مِنَ ٱلنَّارِ","en":"Those who followed will say, \"If only we had another turn [at worldly life] so we could disassociate ourselves from them as they have disassociated themselves from us.\" Thus will Allāh show them their deeds as regrets upon them. And they are never to emerge from the Fire.","tr":"Waqala allatheena ittabaAAoolaw anna lana karratan fanatabarraa minhum kamatabarraoo minna kathalika yureehimu AllahuaAAmalahum hasaratin AAalayhim wamahum bikharijeena mina annar","juz":2,"page":25},{"s":2,"a":168,"key":"2:168","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ كُلُوا۟ مِمَّا فِى ٱلْأَرْضِ حَلَـٰلًا طَيِّبًا وَلَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَـٰنِ ۚ إِنَّهُۥ لَكُمْ عَدُوٌّ مُّبِينٌ","en":"O mankind, eat from whatever is on earth [that is] lawful and good and do not follow the footsteps of Satan. Indeed, he is to you a clear enemy.","tr":"Ya ayyuha annasukuloo mimma fee al-ardi halalan tayyibanwala tattabiAAoo khutuwati ashshaytaniinnahu lakum AAaduwwun mubeen","juz":2,"page":25},{"s":2,"a":169,"key":"2:169","ar":"إِنَّمَا يَأْمُرُكُم بِٱلسُّوٓءِ وَٱلْفَحْشَآءِ وَأَن تَقُولُوا۟ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ","en":"He only orders you to evil and immorality and to say about Allāh what you do not know.","tr":"Innama ya/murukum bissoo-iwalfahsha-i waan taqooloo AAala Allahima la taAAlamoon","juz":2,"page":25},{"s":2,"a":170,"key":"2:170","ar":"وَإِذَا قِيلَ لَهُمُ ٱتَّبِعُوا۟ مَآ أَنزَلَ ٱللَّهُ قَالُوا۟ بَلْ نَتَّبِعُ مَآ أَلْفَيْنَا عَلَيْهِ ءَابَآءَنَآ ۗ أَوَلَوْ كَانَ ءَابَآؤُهُمْ لَا يَعْقِلُونَ شَيْـًٔا وَلَا يَهْتَدُونَ","en":"And when it is said to them, \"Follow what Allāh has revealed,\" they say, \"Rather, we will follow that which we found our fathers doing.\" Even though their fathers understood nothing, nor were they guided?","tr":"Wa-itha qeela lahumu ittabiAAoo maanzala Allahu qaloo bal nattabiAAu ma alfaynaAAalayhi abaana awa law kana abaohumla yaAAqiloona shay-an wala yahtadoon","juz":2,"page":26},{"s":2,"a":171,"key":"2:171","ar":"وَمَثَلُ ٱلَّذِينَ كَفَرُوا۟ كَمَثَلِ ٱلَّذِى يَنْعِقُ بِمَا لَا يَسْمَعُ إِلَّا دُعَآءً وَنِدَآءً ۚ صُمٌّۢ بُكْمٌ عُمْىٌ فَهُمْ لَا يَعْقِلُونَ","en":"The example of those who disbelieve is like that of one who shouts at what hears nothing but calls and cries [i.e., cattle or sheep] - deaf, dumb and blind, so they do not understand.","tr":"Wamathalu allatheena kafarookamathali allathee yanAAiqu bima la yasmaAAuilla duAAaan wanidaan summun bukmunAAumyun fahum la yaAAqiloon","juz":2,"page":26},{"s":2,"a":172,"key":"2:172","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُلُوا۟ مِن طَيِّبَـٰتِ مَا رَزَقْنَـٰكُمْ وَٱشْكُرُوا۟ لِلَّهِ إِن كُنتُمْ إِيَّاهُ تَعْبُدُونَ","en":"O you who have believed, eat from the good [i.e., lawful] things which We have provided for you and be grateful to Allāh if it is [indeed] Him that you worship.","tr":"Ya ayyuha allatheena amanookuloo min tayyibati ma razaqnakum washkuroolillahi in kuntum iyyahu taAAbudoon","juz":2,"page":26},{"s":2,"a":173,"key":"2:173","ar":"إِنَّمَا حَرَّمَ عَلَيْكُمُ ٱلْمَيْتَةَ وَٱلدَّمَ وَلَحْمَ ٱلْخِنزِيرِ وَمَآ أُهِلَّ بِهِۦ لِغَيْرِ ٱللَّهِ ۖ فَمَنِ ٱضْطُرَّ غَيْرَ بَاغٍ وَلَا عَادٍ فَلَآ إِثْمَ عَلَيْهِ ۚ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"He has only forbidden to you dead animals,1 blood, the flesh of swine, and that which has been dedicated to other than Allāh. But whoever is forced [by necessity], neither desiring [it] nor transgressing [its limit], there is no sin upon him. Indeed, Allāh is Forgiving and Merciful.","tr":"Innama harrama AAalaykumualmaytata waddama walahma alkhinzeeri wamaohilla bihi lighayri Allahi famani idturra ghayra baghinwala AAadin fala ithma AAalayhi inna Allahaghafoorun raheem","juz":2,"page":26},{"s":2,"a":174,"key":"2:174","ar":"إِنَّ ٱلَّذِينَ يَكْتُمُونَ مَآ أَنزَلَ ٱللَّهُ مِنَ ٱلْكِتَـٰبِ وَيَشْتَرُونَ بِهِۦ ثَمَنًا قَلِيلًا ۙ أُو۟لَـٰٓئِكَ مَا يَأْكُلُونَ فِى بُطُونِهِمْ إِلَّا ٱلنَّارَ وَلَا يُكَلِّمُهُمُ ٱللَّهُ يَوْمَ ٱلْقِيَـٰمَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"Indeed, they who conceal what Allāh has sent down of the Book and exchange it for a small price - those consume not into their bellies except the Fire. And Allāh will not speak to them on the Day of Resurrection, nor will He purify them. And they will have a painful punishment.","tr":"Inna allatheena yaktumoona maanzala Allahu mina alkitabi wayashtaroona bihithamanan qaleelan ola-ika ma ya/kuloona fee butoonihimilla annara wala yukallimuhumu Allahuyawma alqiyamati wala yuzakkeehim walahum AAathabunaleem","juz":2,"page":26},{"s":2,"a":175,"key":"2:175","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلضَّلَـٰلَةَ بِٱلْهُدَىٰ وَٱلْعَذَابَ بِٱلْمَغْفِرَةِ ۚ فَمَآ أَصْبَرَهُمْ عَلَى ٱلنَّارِ","en":"Those are the ones who have exchanged guidance for error and forgiveness for punishment. How patient they are for [i.e., in pursuit of] the Fire!","tr":"Ola-ika allatheena ishtarawooaddalalata bilhuda walAAathababilmaghfirati fama asbarahum AAala annar","juz":2,"page":26},{"s":2,"a":176,"key":"2:176","ar":"ذَٰلِكَ بِأَنَّ ٱللَّهَ نَزَّلَ ٱلْكِتَـٰبَ بِٱلْحَقِّ ۗ وَإِنَّ ٱلَّذِينَ ٱخْتَلَفُوا۟ فِى ٱلْكِتَـٰبِ لَفِى شِقَاقٍۭ بَعِيدٍ","en":"That is [deserved by them] because Allāh has sent down the Book in truth. And indeed, those who differ over the Book are in extreme dissension.","tr":"Thalika bi-anna Allahanazzala alkitaba bilhaqqi wa-inna allatheenaikhtalafoo fee alkitabi lafee shiqaqin baAAeed","juz":2,"page":26},{"s":2,"a":177,"key":"2:177","ar":"۞ لَّيْسَ ٱلْبِرَّ أَن تُوَلُّوا۟ وُجُوهَكُمْ قِبَلَ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ وَلَـٰكِنَّ ٱلْبِرَّ مَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ وَٱلْمَلَـٰٓئِكَةِ وَٱلْكِتَـٰبِ وَٱلنَّبِيِّـۧنَ وَءَاتَى ٱلْمَالَ عَلَىٰ حُبِّهِۦ ذَوِى ٱلْقُرْبَىٰ وَٱلْيَتَـٰمَىٰ وَٱلْمَسَـٰكِينَ وَٱبْنَ ٱلسَّبِيلِ وَٱلسَّآئِلِينَ وَفِى ٱلرِّقَابِ وَأَقَامَ ٱلصَّلَوٰةَ وَءَاتَى ٱلزَّكَوٰةَ وَٱلْمُوفُونَ بِعَهْدِهِمْ إِذَا عَـٰهَدُوا۟ ۖ وَٱلصَّـٰبِرِينَ فِى ٱلْبَأْسَآءِ وَٱلضَّرَّآءِ وَحِينَ ٱلْبَأْسِ ۗ أُو۟لَـٰٓئِكَ ٱلَّذِينَ صَدَقُوا۟ ۖ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُتَّقُونَ","en":"Righteousness is not that you turn your faces toward the east or the west, but [true] righteousness is [in] one who believes in Allāh, the Last Day, the angels, the Book, and the prophets and gives wealth, in spite of love for it, to relatives, orphans, the needy, the traveler, those who ask [for help], and for freeing slaves; [and who] establishes prayer and gives zakāh; [those who] fulfill their promise when they promise; and [those who] are patient in poverty and hardship and during battle. Those are the ones who have been true, and it is those who are the righteous.","tr":"Laysa albirra an tuwalloo wujoohakum qibalaalmashriqi walmaghribi walakinna albirra man amanabillahi walyawmi al-akhiri walmala-ikatiwalkitabi wannabiyyeena waataalmala AAala hubbihi thawee alqurbawalyatama walmasakeena wabnaalssabeeli wassa-ileena wafee arriqabiwaaqama assalata waataazzakata walmoofoona biAAahdihim ithaAAahadoo wassabireena fee alba/sa-iwaddarra-i waheena alba/si ola-ikaallatheena sadaqoo waola-ika humualmuttaqoon","juz":2,"page":27},{"s":2,"a":178,"key":"2:178","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُتِبَ عَلَيْكُمُ ٱلْقِصَاصُ فِى ٱلْقَتْلَى ۖ ٱلْحُرُّ بِٱلْحُرِّ وَٱلْعَبْدُ بِٱلْعَبْدِ وَٱلْأُنثَىٰ بِٱلْأُنثَىٰ ۚ فَمَنْ عُفِىَ لَهُۥ مِنْ أَخِيهِ شَىْءٌ فَٱتِّبَاعٌۢ بِٱلْمَعْرُوفِ وَأَدَآءٌ إِلَيْهِ بِإِحْسَـٰنٍ ۗ ذَٰلِكَ تَخْفِيفٌ مِّن رَّبِّكُمْ وَرَحْمَةٌ ۗ فَمَنِ ٱعْتَدَىٰ بَعْدَ ذَٰلِكَ فَلَهُۥ عَذَابٌ أَلِيمٌ","en":"O you who have believed, prescribed for you is legal retribution for those murdered - the free for the free, the slave for the slave, and the female for the female.1 But whoever overlooks from his brother [i.e., the killer] anything,2 then there should be a suitable follow-up and payment to him [i.e., the deceased's heir or legal representative] with good conduct. This is an alleviation from your Lord and a mercy. But whoever transgresses after that3 will have a painful punishment.","tr":"Ya ayyuha allatheena amanookutiba AAalaykumu alqisasu fee alqatla alhurrubilhurri walAAabdu bilAAabdi walonthabilontha faman AAufiya lahu min akheehi shay-on fattibaAAunbilmaAAroofi waadaon ilayhi bi-ihsaninthalika takhfeefun min rabbikum warahmatun famaniiAAtada baAAda thalika falahu AAathabunaleem","juz":2,"page":27},{"s":2,"a":179,"key":"2:179","ar":"وَلَكُمْ فِى ٱلْقِصَاصِ حَيَوٰةٌ يَـٰٓأُو۟لِى ٱلْأَلْبَـٰبِ لَعَلَّكُمْ تَتَّقُونَ","en":"And there is for you in legal retribution [saving of] life, O you [people] of understanding, that you may become righteous.1","tr":"Walakum fee alqisasi hayatunya olee al-albabi laAAallakum tattaqoon","juz":2,"page":27},{"s":2,"a":180,"key":"2:180","ar":"كُتِبَ عَلَيْكُمْ إِذَا حَضَرَ أَحَدَكُمُ ٱلْمَوْتُ إِن تَرَكَ خَيْرًا ٱلْوَصِيَّةُ لِلْوَٰلِدَيْنِ وَٱلْأَقْرَبِينَ بِٱلْمَعْرُوفِ ۖ حَقًّا عَلَى ٱلْمُتَّقِينَ","en":"Prescribed for you when death approaches [any] one of you if he leaves wealth [is that he should make] a bequest for the parents and near relatives according to what is acceptable - a duty upon the righteous.1","tr":"Kutiba AAalaykum itha hadaraahadakumu almawtu in taraka khayran alwasiyyatulilwalidayni wal-aqrabeena bilmaAAroofi haqqanAAala almuttaqeen","juz":2,"page":27},{"s":2,"a":181,"key":"2:181","ar":"فَمَنۢ بَدَّلَهُۥ بَعْدَ مَا سَمِعَهُۥ فَإِنَّمَآ إِثْمُهُۥ عَلَى ٱلَّذِينَ يُبَدِّلُونَهُۥٓ ۚ إِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌ","en":"Then whoever alters it [i.e., the bequest] after he has heard it - the sin is only upon those who have altered it. Indeed, Allāh is Hearing and Knowing.","tr":"Faman baddalahu baAAda ma samiAAahufa-innama ithmuhu AAala allatheenayubaddiloonahu inna Allaha sameeAAun AAaleem","juz":2,"page":27},{"s":2,"a":182,"key":"2:182","ar":"فَمَنْ خَافَ مِن مُّوصٍ جَنَفًا أَوْ إِثْمًا فَأَصْلَحَ بَيْنَهُمْ فَلَآ إِثْمَ عَلَيْهِ ۚ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"But if one fears from the bequeather [some] error or sin and corrects that which is between them [i.e., the concerned parties], there is no sin upon him. Indeed, Allāh is Forgiving and Merciful.","tr":"Faman khafa min moosinjanafan aw ithman faaslaha baynahum falaithma AAalayhi inna Allaha ghafoorun raheem","juz":2,"page":28},{"s":2,"a":183,"key":"2:183","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُتِبَ عَلَيْكُمُ ٱلصِّيَامُ كَمَا كُتِبَ عَلَى ٱلَّذِينَ مِن قَبْلِكُمْ لَعَلَّكُمْ تَتَّقُونَ","en":"O you who have believed, decreed upon you is fasting as it was decreed upon those before you that you may become righteous -","tr":"Ya ayyuha allatheena amanookutiba AAalaykumu assiyamu kamakutiba AAala allatheena min qablikum laAAallakumtattaqoon","juz":2,"page":28},{"s":2,"a":184,"key":"2:184","ar":"أَيَّامًا مَّعْدُودَٰتٍ ۚ فَمَن كَانَ مِنكُم مَّرِيضًا أَوْ عَلَىٰ سَفَرٍ فَعِدَّةٌ مِّنْ أَيَّامٍ أُخَرَ ۚ وَعَلَى ٱلَّذِينَ يُطِيقُونَهُۥ فِدْيَةٌ طَعَامُ مِسْكِينٍ ۖ فَمَن تَطَوَّعَ خَيْرًا فَهُوَ خَيْرٌ لَّهُۥ ۚ وَأَن تَصُومُوا۟ خَيْرٌ لَّكُمْ ۖ إِن كُنتُمْ تَعْلَمُونَ","en":"[Fasting for] a limited number of days. So whoever among you is ill or on a journey [during them] - then an equal number of other days [are to be made up]. And upon those who are able [to fast, but with hardship] - a ransom [as substitute] of feeding a poor person [each day]. And whoever volunteers good [i.e., excess] - it is better for him. But to fast is best for you, if you only knew.","tr":"Ayyaman maAAdoodatin faman kanaminkum mareedan aw AAala safarin faAAiddatun minayyamin okhara waAAala allatheena yuteeqoonahufidyatun taAAamu miskeenin faman tatawwaAAakhayran fahuwa khayrun lahu waan tasoomoo khayrun lakum inkuntum taAAlamoon","juz":2,"page":28},{"s":2,"a":185,"key":"2:185","ar":"شَهْرُ رَمَضَانَ ٱلَّذِىٓ أُنزِلَ فِيهِ ٱلْقُرْءَانُ هُدًى لِّلنَّاسِ وَبَيِّنَـٰتٍ مِّنَ ٱلْهُدَىٰ وَٱلْفُرْقَانِ ۚ فَمَن شَهِدَ مِنكُمُ ٱلشَّهْرَ فَلْيَصُمْهُ ۖ وَمَن كَانَ مَرِيضًا أَوْ عَلَىٰ سَفَرٍ فَعِدَّةٌ مِّنْ أَيَّامٍ أُخَرَ ۗ يُرِيدُ ٱللَّهُ بِكُمُ ٱلْيُسْرَ وَلَا يُرِيدُ بِكُمُ ٱلْعُسْرَ وَلِتُكْمِلُوا۟ ٱلْعِدَّةَ وَلِتُكَبِّرُوا۟ ٱللَّهَ عَلَىٰ مَا هَدَىٰكُمْ وَلَعَلَّكُمْ تَشْكُرُونَ","en":"The month of Ramaḍān [is that] in which was revealed the Qur’ān, a guidance for the people and clear proofs of guidance and criterion. So whoever sights [the crescent of] the month,1 let him fast it; and whoever is ill or on a journey - then an equal number of other days. Allāh intends for you ease and does not intend for you hardship and [wants] for you to complete the period and to glorify Allāh for that [to] which He has guided you; and perhaps you will be grateful.","tr":"Shahru ramadana allatheeonzila feehi alqur-anu hudan linnasiwabayyinatin mina alhuda walfurqanifaman shahida minkumu ashshahra falyasumhu waman kanamareedan aw AAala safarin faAAiddatun min ayyaminokhara yureedu Allahu bikumu alyusra wala yureedubikumu alAAusra walitukmiloo alAAiddata walitukabbiroo AllahaAAala ma hadakum walaAAallakum tashkuroon","juz":2,"page":28},{"s":2,"a":186,"key":"2:186","ar":"وَإِذَا سَأَلَكَ عِبَادِى عَنِّى فَإِنِّى قَرِيبٌ ۖ أُجِيبُ دَعْوَةَ ٱلدَّاعِ إِذَا دَعَانِ ۖ فَلْيَسْتَجِيبُوا۟ لِى وَلْيُؤْمِنُوا۟ بِى لَعَلَّهُمْ يَرْشُدُونَ","en":"And when My servants ask you, [O Muḥammad], concerning Me - indeed I am near. I respond to the invocation of the supplicant when he calls upon Me. So let them respond to Me [by obedience] and believe in Me that they may be [rightly] guided.","tr":"Wa-itha saalaka AAibadeeAAannee fa-innee qareebun ojeebu daAAwata addaAAiitha daAAani falyastajeeboo lee walyu/minoo beelaAAallahum yarshudoon","juz":2,"page":28},{"s":2,"a":187,"key":"2:187","ar":"أُحِلَّ لَكُمْ لَيْلَةَ ٱلصِّيَامِ ٱلرَّفَثُ إِلَىٰ نِسَآئِكُمْ ۚ هُنَّ لِبَاسٌ لَّكُمْ وَأَنتُمْ لِبَاسٌ لَّهُنَّ ۗ عَلِمَ ٱللَّهُ أَنَّكُمْ كُنتُمْ تَخْتَانُونَ أَنفُسَكُمْ فَتَابَ عَلَيْكُمْ وَعَفَا عَنكُمْ ۖ فَٱلْـَٔـٰنَ بَـٰشِرُوهُنَّ وَٱبْتَغُوا۟ مَا كَتَبَ ٱللَّهُ لَكُمْ ۚ وَكُلُوا۟ وَٱشْرَبُوا۟ حَتَّىٰ يَتَبَيَّنَ لَكُمُ ٱلْخَيْطُ ٱلْأَبْيَضُ مِنَ ٱلْخَيْطِ ٱلْأَسْوَدِ مِنَ ٱلْفَجْرِ ۖ ثُمَّ أَتِمُّوا۟ ٱلصِّيَامَ إِلَى ٱلَّيْلِ ۚ وَلَا تُبَـٰشِرُوهُنَّ وَأَنتُمْ عَـٰكِفُونَ فِى ٱلْمَسَـٰجِدِ ۗ تِلْكَ حُدُودُ ٱللَّهِ فَلَا تَقْرَبُوهَا ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ ءَايَـٰتِهِۦ لِلنَّاسِ لَعَلَّهُمْ يَتَّقُونَ","en":"It has been made permissible for you the night preceding fasting to go to your wives [for sexual relations]. They are a clothing for you and you are a clothing1 for them. Allāh knows that you used to deceive yourselves,2 so He accepted your repentance and forgave you. So now, have relations with them and seek that which Allāh has decreed for you [i.e., offspring]. And eat and drink until the white thread of dawn becomes distinct to you from the black thread [of night]. Then complete the fast until the night [i.e., sunset]. And do not have relations with them as long as you are staying for worship in the mosques. These are the limits [set by] Allāh, so do not approach them. Thus does Allāh make clear His verses [i.e., ordinances] to the people that they may become righteous.","tr":"Ohilla lakum laylata assiyamiarrafathu ila nisa-ikum hunna libasunlakum waantum libasun lahunna AAalima Allahuannakum kuntum takhtanoona anfusakum fatabaAAalaykum waAAafa AAankum fal-ana bashiroohunnawabtaghoo ma kataba Allahu lakum wakuloo washraboohatta yatabayyana lakumu alkhaytu al-abyadumina alkhayti al-aswadi mina alfajri thumma atimmoo assiyamaila allayli wala tubashiroohunna waantum AAakifoonafee almasajidi tilka hudoodu Allahi falataqrabooha kathalika yubayyinu Allahu ayatihilinnasi laAAallahum yattaqoon","juz":2,"page":29},{"s":2,"a":188,"key":"2:188","ar":"وَلَا تَأْكُلُوٓا۟ أَمْوَٰلَكُم بَيْنَكُم بِٱلْبَـٰطِلِ وَتُدْلُوا۟ بِهَآ إِلَى ٱلْحُكَّامِ لِتَأْكُلُوا۟ فَرِيقًا مِّنْ أَمْوَٰلِ ٱلنَّاسِ بِٱلْإِثْمِ وَأَنتُمْ تَعْلَمُونَ","en":"And do not consume one another's wealth unjustly or send it [in bribery] to the rulers in order that [they might aid] you [to] consume a portion of the wealth of the people in sin, while you know [it is unlawful].","tr":"Wala ta/kuloo amwalakumbaynakum bilbatili watudloo biha ilaalhukkami lita/kuloo fareeqan min amwali annasibil-ithmi waantum taAAlamoon","juz":2,"page":29},{"s":2,"a":189,"key":"2:189","ar":"۞ يَسْـَٔلُونَكَ عَنِ ٱلْأَهِلَّةِ ۖ قُلْ هِىَ مَوَٰقِيتُ لِلنَّاسِ وَٱلْحَجِّ ۗ وَلَيْسَ ٱلْبِرُّ بِأَن تَأْتُوا۟ ٱلْبُيُوتَ مِن ظُهُورِهَا وَلَـٰكِنَّ ٱلْبِرَّ مَنِ ٱتَّقَىٰ ۗ وَأْتُوا۟ ٱلْبُيُوتَ مِنْ أَبْوَٰبِهَا ۚ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُفْلِحُونَ","en":"They ask you, [O Muḥammad], about the crescent moons. Say, \"They are measurements of time for the people and for ḥajj [pilgrimage].\" And it is not righteousness to enter houses from the back, but righteousness is [in] one who fears Allāh. And enter houses from their doors. And fear Allāh that you may succeed.","tr":"Yas-aloonaka AAani al-ahillati qul hiya mawaqeetulinnasi walhajji walaysa albirrubi-an ta/too albuyoota min thuhooriha walakinnaalbirra mani ittaqa wa/too albuyoota min abwabihawattaqoo Allaha laAAallakum tuflihoon","juz":2,"page":29},{"s":2,"a":190,"key":"2:190","ar":"وَقَـٰتِلُوا۟ فِى سَبِيلِ ٱللَّهِ ٱلَّذِينَ يُقَـٰتِلُونَكُمْ وَلَا تَعْتَدُوٓا۟ ۚ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْمُعْتَدِينَ","en":"Fight in the way of Allāh those who fight against you but do not transgress. Indeed, Allāh does not like transgressors.","tr":"Waqatiloo fee sabeeli Allahiallatheena yuqatiloonakum wala taAAtadooinna Allaha la yuhibbu almuAAtadeen","juz":2,"page":29},{"s":2,"a":191,"key":"2:191","ar":"وَٱقْتُلُوهُمْ حَيْثُ ثَقِفْتُمُوهُمْ وَأَخْرِجُوهُم مِّنْ حَيْثُ أَخْرَجُوكُمْ ۚ وَٱلْفِتْنَةُ أَشَدُّ مِنَ ٱلْقَتْلِ ۚ وَلَا تُقَـٰتِلُوهُمْ عِندَ ٱلْمَسْجِدِ ٱلْحَرَامِ حَتَّىٰ يُقَـٰتِلُوكُمْ فِيهِ ۖ فَإِن قَـٰتَلُوكُمْ فَٱقْتُلُوهُمْ ۗ كَذَٰلِكَ جَزَآءُ ٱلْكَـٰفِرِينَ","en":"And kill them [in battle] wherever you overtake them and expel them from wherever they have expelled you, and fitnah1 is worse than killing. And do not fight them at al-Masjid al-Ḥarām until they fight you there. But if they fight you, then kill them. Such is the recompense of the disbelievers.","tr":"Waqtuloohum haythuthaqiftumoohum waakhrijoohum min haythu akhrajookum walfitnatuashaddu mina alqatli wala tuqatiloohum AAindaalmasjidi alharami hatta yuqatilookumfeehi fa-in qatalookum faqtuloohum kathalikajazao alkafireen","juz":2,"page":30},{"s":2,"a":192,"key":"2:192","ar":"فَإِنِ ٱنتَهَوْا۟ فَإِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"And if they cease, then indeed, Allāh is Forgiving and Merciful.","tr":"Fa-ini intahaw fa-inna Allahaghafoorun raheem","juz":2,"page":30},{"s":2,"a":193,"key":"2:193","ar":"وَقَـٰتِلُوهُمْ حَتَّىٰ لَا تَكُونَ فِتْنَةٌ وَيَكُونَ ٱلدِّينُ لِلَّهِ ۖ فَإِنِ ٱنتَهَوْا۟ فَلَا عُدْوَٰنَ إِلَّا عَلَى ٱلظَّـٰلِمِينَ","en":"Fight them until there is no [more] fitnah and [until] religion [i.e., worship] is [acknowledged to be] for Allāh. But if they cease, then there is to be no aggression [i.e., assault] except against the oppressors.","tr":"Waqatiloohum hatta latakoona fitnatun wayakoona addeenu lillahi fa-iniintahaw fala AAudwana illa AAala aththalimeen","juz":2,"page":30},{"s":2,"a":194,"key":"2:194","ar":"ٱلشَّهْرُ ٱلْحَرَامُ بِٱلشَّهْرِ ٱلْحَرَامِ وَٱلْحُرُمَـٰتُ قِصَاصٌ ۚ فَمَنِ ٱعْتَدَىٰ عَلَيْكُمْ فَٱعْتَدُوا۟ عَلَيْهِ بِمِثْلِ مَا ٱعْتَدَىٰ عَلَيْكُمْ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ مَعَ ٱلْمُتَّقِينَ","en":"[Battle in] the sacred month is for [aggression committed in] the sacred month,1 and for [all] violations is legal retribution. So whoever has assaulted you, then assault him in the same way that he has assaulted you. And fear Allāh and know that Allāh is with those who fear Him.","tr":"Ashshahru alharamu bishshahrialharami walhurumatu qisasunfamani iAAtada AAalaykum faAAtadoo AAalayhibimithli ma iAAtada AAalaykum wattaqoo AllahawaAAlamoo anna Allaha maAAa almuttaqeen","juz":2,"page":30},{"s":2,"a":195,"key":"2:195","ar":"وَأَنفِقُوا۟ فِى سَبِيلِ ٱللَّهِ وَلَا تُلْقُوا۟ بِأَيْدِيكُمْ إِلَى ٱلتَّهْلُكَةِ ۛ وَأَحْسِنُوٓا۟ ۛ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُحْسِنِينَ","en":"And spend in the way of Allāh and do not throw [yourselves] with your [own] hands into destruction [by refraining]. And do good; indeed, Allāh loves the doers of good.","tr":"Waanfiqoo fee sabeeli Allahi walatulqoo bi-aydeekum ila attahlukati waahsinooinna Allaha yuhibbu almuhsineen","juz":2,"page":30},{"s":2,"a":196,"key":"2:196","ar":"وَأَتِمُّوا۟ ٱلْحَجَّ وَٱلْعُمْرَةَ لِلَّهِ ۚ فَإِنْ أُحْصِرْتُمْ فَمَا ٱسْتَيْسَرَ مِنَ ٱلْهَدْىِ ۖ وَلَا تَحْلِقُوا۟ رُءُوسَكُمْ حَتَّىٰ يَبْلُغَ ٱلْهَدْىُ مَحِلَّهُۥ ۚ فَمَن كَانَ مِنكُم مَّرِيضًا أَوْ بِهِۦٓ أَذًى مِّن رَّأْسِهِۦ فَفِدْيَةٌ مِّن صِيَامٍ أَوْ صَدَقَةٍ أَوْ نُسُكٍ ۚ فَإِذَآ أَمِنتُمْ فَمَن تَمَتَّعَ بِٱلْعُمْرَةِ إِلَى ٱلْحَجِّ فَمَا ٱسْتَيْسَرَ مِنَ ٱلْهَدْىِ ۚ فَمَن لَّمْ يَجِدْ فَصِيَامُ ثَلَـٰثَةِ أَيَّامٍ فِى ٱلْحَجِّ وَسَبْعَةٍ إِذَا رَجَعْتُمْ ۗ تِلْكَ عَشَرَةٌ كَامِلَةٌ ۗ ذَٰلِكَ لِمَن لَّمْ يَكُنْ أَهْلُهُۥ حَاضِرِى ٱلْمَسْجِدِ ٱلْحَرَامِ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ","en":"And complete the ḥajj and ʿumrah for Allāh. But if you are prevented, then [offer] what can be obtained with ease of sacrificial animals. And do not shave your heads until the sacrificial animal has reached its place of slaughter. And whoever among you is ill or has an ailment of the head [making shaving necessary must offer] a ransom of fasting [three days] or charity1 or sacrifice.2 And when you are secure,3 then whoever performs ʿumrah [during the ḥajj months]4 followed by ḥajj [offers] what can be obtained with ease of sacrificial animals. And whoever cannot find [or afford such an animal] - then a fast of three days during ḥajj and of seven when you have returned [home]. Those are ten complete [days]. This is for those whose family is not in the area of al-Masjid al-Ḥarām. And fear Allāh and know that Allāh is severe in penalty.","tr":"Waatimmoo alhajja walAAumratalillahi fa-in ohsirtum fama istaysara minaalhadyi wala tahliqoo ruoosakum hattayablugha alhadyu mahillahu faman kana minkum mareedanaw bihi athan min ra/sihi fafidyatun min siyaminaw sadaqatin aw nusukin fa-itha amintum famantamattaAAa bilAAumrati ila alhajji famaistaysara mina alhadyi faman lam yajid fasiyamuthalathati ayyamin fee alhajji wasabAAatin itharajaAAtum tilka AAasharatun kamilatun thalika limanlam yakun ahluhu hadiree almasjidi alharamiwattaqoo Allaha waAAlamoo anna Allahashadeedu alAAiqab","juz":2,"page":30},{"s":2,"a":197,"key":"2:197","ar":"ٱلْحَجُّ أَشْهُرٌ مَّعْلُومَـٰتٌ ۚ فَمَن فَرَضَ فِيهِنَّ ٱلْحَجَّ فَلَا رَفَثَ وَلَا فُسُوقَ وَلَا جِدَالَ فِى ٱلْحَجِّ ۗ وَمَا تَفْعَلُوا۟ مِنْ خَيْرٍ يَعْلَمْهُ ٱللَّهُ ۗ وَتَزَوَّدُوا۟ فَإِنَّ خَيْرَ ٱلزَّادِ ٱلتَّقْوَىٰ ۚ وَٱتَّقُونِ يَـٰٓأُو۟لِى ٱلْأَلْبَـٰبِ","en":"Ḥajj is [during] well-known months,1 so whoever has made ḥajj obligatory upon himself therein [by entering the state of iḥrām], there is [to be for him] no sexual relations and no disobedience and no disputing during ḥajj. And whatever good you do - Allāh knows it. And take provisions, but indeed, the best provision is fear of Allāh. And fear Me, O you of understanding.","tr":"Alhajju ashhurun maAAloomatunfaman farada feehinna alhajja fala rafathawala fusooqa wala jidala fee alhajjiwama tafAAaloo min khayrin yaAAlamhu Allahuwatazawwadoo fa-inna khayra azzadi attaqwawattaqooni ya olee al-albab","juz":2,"page":31},{"s":2,"a":198,"key":"2:198","ar":"لَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَبْتَغُوا۟ فَضْلًا مِّن رَّبِّكُمْ ۚ فَإِذَآ أَفَضْتُم مِّنْ عَرَفَـٰتٍ فَٱذْكُرُوا۟ ٱللَّهَ عِندَ ٱلْمَشْعَرِ ٱلْحَرَامِ ۖ وَٱذْكُرُوهُ كَمَا هَدَىٰكُمْ وَإِن كُنتُم مِّن قَبْلِهِۦ لَمِنَ ٱلضَّآلِّينَ","en":"There is no blame upon you for seeking bounty1 from your Lord [during ḥajj]. But when you depart from ʿArafāt, remember Allāh at al-Mashʿar al-Ḥarām.2 And remember Him, as He has guided you, for indeed, you were before that among those astray.","tr":"Laysa AAalaykum junahun an tabtaghoofadlan min rabbikum fa-itha afadtum minAAarafatin fathkuroo Allaha AAindaalmashAAari alharami wathkuroohu kamahadakum wa-in kuntum min qablihi lamina addalleen","juz":2,"page":31},{"s":2,"a":199,"key":"2:199","ar":"ثُمَّ أَفِيضُوا۟ مِنْ حَيْثُ أَفَاضَ ٱلنَّاسُ وَٱسْتَغْفِرُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"Then depart from the place from where [all] the people depart and ask forgiveness of Allāh. Indeed, Allāh is Forgiving and Merciful.","tr":"Thumma afeedoo min haythu afadaannasu wastaghfiroo Allaha inna Allahaghafoorun raheem","juz":2,"page":31},{"s":2,"a":200,"key":"2:200","ar":"فَإِذَا قَضَيْتُم مَّنَـٰسِكَكُمْ فَٱذْكُرُوا۟ ٱللَّهَ كَذِكْرِكُمْ ءَابَآءَكُمْ أَوْ أَشَدَّ ذِكْرًا ۗ فَمِنَ ٱلنَّاسِ مَن يَقُولُ رَبَّنَآ ءَاتِنَا فِى ٱلدُّنْيَا وَمَا لَهُۥ فِى ٱلْـَٔاخِرَةِ مِنْ خَلَـٰقٍ","en":"And when you have completed your rites, remember Allāh like your [previous] remembrance of your fathers or with [much] greater remembrance. And among the people is he who says, \"Our Lord, give us in this world,\" and he will have in the Hereafter no share.","tr":"Fa-itha qadaytum manasikakumfathkuroo Allaha kathikrikum abaakumaw ashadda thikran famina annasi manyaqoolu rabbana atina fee addunyawama lahu fee al-akhirati min khalaq","juz":2,"page":31},{"s":2,"a":201,"key":"2:201","ar":"وَمِنْهُم مَّن يَقُولُ رَبَّنَآ ءَاتِنَا فِى ٱلدُّنْيَا حَسَنَةً وَفِى ٱلْـَٔاخِرَةِ حَسَنَةً وَقِنَا عَذَابَ ٱلنَّارِ","en":"But among them is he who says, \"Our Lord, give us in this world [that which is] good and in the Hereafter [that which is] good and protect us from the punishment of the Fire.\"","tr":"Waminhum man yaqoolu rabbana atinafee addunya hasanatan wafee al-akhiratihasanatan waqina AAathaba annar","juz":2,"page":31},{"s":2,"a":202,"key":"2:202","ar":"أُو۟لَـٰٓئِكَ لَهُمْ نَصِيبٌ مِّمَّا كَسَبُوا۟ ۚ وَٱللَّهُ سَرِيعُ ٱلْحِسَابِ","en":"Those will have a share of what they have earned, and Allāh is swift in account.","tr":"Ola-ika lahum naseebun mimmakasaboo wallahu sareeAAu alhisab","juz":2,"page":31},{"s":2,"a":203,"key":"2:203","ar":"۞ وَٱذْكُرُوا۟ ٱللَّهَ فِىٓ أَيَّامٍ مَّعْدُودَٰتٍ ۚ فَمَن تَعَجَّلَ فِى يَوْمَيْنِ فَلَآ إِثْمَ عَلَيْهِ وَمَن تَأَخَّرَ فَلَآ إِثْمَ عَلَيْهِ ۚ لِمَنِ ٱتَّقَىٰ ۗ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّكُمْ إِلَيْهِ تُحْشَرُونَ","en":"And remember Allāh during [specific] numbered days. Then whoever hastens [his departure] in two days - there is no sin upon him; and whoever delays [until the third] - there is no sin upon him - for him who fears Allāh. And fear Allāh and know that unto Him you will be gathered.","tr":"Wathkuroo Allaha feeayyamin maAAdoodatin faman taAAajjala fee yawmaynifala ithma AAalayhi waman taakhkhara fala ithmaAAalayhi limani ittaqa wattaqoo Allaha waAAlamooannakum ilayhi tuhsharoon","juz":2,"page":32},{"s":2,"a":204,"key":"2:204","ar":"وَمِنَ ٱلنَّاسِ مَن يُعْجِبُكَ قَوْلُهُۥ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَيُشْهِدُ ٱللَّهَ عَلَىٰ مَا فِى قَلْبِهِۦ وَهُوَ أَلَدُّ ٱلْخِصَامِ","en":"And of the people is he whose speech pleases you in worldly life, and he calls Allāh to witness as to what is in his heart, yet he is the fiercest of opponents.","tr":"Wamina annasi man yuAAjibukaqawluhu fee alhayati addunyawayushhidu Allaha AAala ma fee qalbihiwahuwa aladdu alkhisam","juz":2,"page":32},{"s":2,"a":205,"key":"2:205","ar":"وَإِذَا تَوَلَّىٰ سَعَىٰ فِى ٱلْأَرْضِ لِيُفْسِدَ فِيهَا وَيُهْلِكَ ٱلْحَرْثَ وَٱلنَّسْلَ ۗ وَٱللَّهُ لَا يُحِبُّ ٱلْفَسَادَ","en":"And when he goes away, he strives throughout the land to cause corruption therein and destroy crops and animals. And Allāh does not like corruption.","tr":"Wa-itha tawalla saAAafee al-ardi liyufsida feeha wayuhlika alharthawannasla wallahu la yuhibbualfasad","juz":2,"page":32},{"s":2,"a":206,"key":"2:206","ar":"وَإِذَا قِيلَ لَهُ ٱتَّقِ ٱللَّهَ أَخَذَتْهُ ٱلْعِزَّةُ بِٱلْإِثْمِ ۚ فَحَسْبُهُۥ جَهَنَّمُ ۚ وَلَبِئْسَ ٱلْمِهَادُ","en":"And when it is said to him, \"Fear Allāh,\" pride in the sin takes hold of him. Sufficient for him is Hellfire, and how wretched is the resting place.","tr":"Wa-itha qeela lahu ittaqi Allahaakhathat-hu alAAizzatu bil-ithmi fahasbuhujahannamu walabi/sa almihad","juz":2,"page":32},{"s":2,"a":207,"key":"2:207","ar":"وَمِنَ ٱلنَّاسِ مَن يَشْرِى نَفْسَهُ ٱبْتِغَآءَ مَرْضَاتِ ٱللَّهِ ۗ وَٱللَّهُ رَءُوفٌۢ بِٱلْعِبَادِ","en":"And of the people is he who sells himself, seeking means to the approval of Allāh. And Allāh is Kind to [His] servants.","tr":"Wamina annasi man yashreenafsahu ibtighaa mardati Allahi wallahuraoofun bilAAibad","juz":2,"page":32},{"s":2,"a":208,"key":"2:208","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱدْخُلُوا۟ فِى ٱلسِّلْمِ كَآفَّةً وَلَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَـٰنِ ۚ إِنَّهُۥ لَكُمْ عَدُوٌّ مُّبِينٌ","en":"O you who have believed, enter into Islām completely [and perfectly] and do not follow the footsteps of Satan. Indeed, he is to you a clear enemy.","tr":"Ya ayyuha allatheena amanooodkhuloo fee assilmi kaffatan walatattabiAAoo khutuwati ashshaytaniinnahu lakum AAaduwwun mubeen","juz":2,"page":32},{"s":2,"a":209,"key":"2:209","ar":"فَإِن زَلَلْتُم مِّنۢ بَعْدِ مَا جَآءَتْكُمُ ٱلْبَيِّنَـٰتُ فَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ","en":"But if you slip [i.e., deviate] after clear proofs have come to you, then know that Allāh is Exalted in Might and Wise.","tr":"Fa-in zalaltum min baAAdi ma jaatkumualbayyinatu faAAlamoo anna Allaha AAazeezunhakeem","juz":2,"page":32},{"s":2,"a":210,"key":"2:210","ar":"هَلْ يَنظُرُونَ إِلَّآ أَن يَأْتِيَهُمُ ٱللَّهُ فِى ظُلَلٍ مِّنَ ٱلْغَمَامِ وَٱلْمَلَـٰٓئِكَةُ وَقُضِىَ ٱلْأَمْرُ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ","en":"Do they await but that Allāh should come to them in covers of clouds and the angels [as well] and the matter is [then] decided? And to Allāh [all] matters are returned.","tr":"Hal yanthuroona illaan ya/tiyahumu Allahu fee thulalin minaalghamami walmala-ikatu waqudiyaal-amru wa-ila Allahi turjaAAu al-omoor","juz":2,"page":32},{"s":2,"a":211,"key":"2:211","ar":"سَلْ بَنِىٓ إِسْرَٰٓءِيلَ كَمْ ءَاتَيْنَـٰهُم مِّنْ ءَايَةٍۭ بَيِّنَةٍ ۗ وَمَن يُبَدِّلْ نِعْمَةَ ٱللَّهِ مِنۢ بَعْدِ مَا جَآءَتْهُ فَإِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ","en":"Ask the Children of Israel how many a sign of evidence We have given them. And whoever exchanges the favor of Allāh [for disbelief] after it has come to him - then indeed, Allāh is severe in penalty.","tr":"Sal banee isra-eela kam ataynahummin ayatin bayyinatin waman yubaddil niAAmata Allahimin baAAdi ma jaat-hu fa-inna Allahashadeedu alAAiqab","juz":2,"page":33},{"s":2,"a":212,"key":"2:212","ar":"زُيِّنَ لِلَّذِينَ كَفَرُوا۟ ٱلْحَيَوٰةُ ٱلدُّنْيَا وَيَسْخَرُونَ مِنَ ٱلَّذِينَ ءَامَنُوا۟ ۘ وَٱلَّذِينَ ٱتَّقَوْا۟ فَوْقَهُمْ يَوْمَ ٱلْقِيَـٰمَةِ ۗ وَٱللَّهُ يَرْزُقُ مَن يَشَآءُ بِغَيْرِ حِسَابٍ","en":"Beautified for those who disbelieve is the life of this world, and they ridicule those who believe. But those who fear Allāh are above them on the Day of Resurrection. And Allāh gives provision to whom He wills without account.","tr":"Zuyyina lillatheena kafaroo alhayatuaddunya wayaskharoona mina allatheena amanoowallatheena ittaqaw fawqahum yawma alqiyamatiwallahu yarzuqu man yashao bighayri hisab","juz":2,"page":33},{"s":2,"a":213,"key":"2:213","ar":"كَانَ ٱلنَّاسُ أُمَّةً وَٰحِدَةً فَبَعَثَ ٱللَّهُ ٱلنَّبِيِّـۧنَ مُبَشِّرِينَ وَمُنذِرِينَ وَأَنزَلَ مَعَهُمُ ٱلْكِتَـٰبَ بِٱلْحَقِّ لِيَحْكُمَ بَيْنَ ٱلنَّاسِ فِيمَا ٱخْتَلَفُوا۟ فِيهِ ۚ وَمَا ٱخْتَلَفَ فِيهِ إِلَّا ٱلَّذِينَ أُوتُوهُ مِنۢ بَعْدِ مَا جَآءَتْهُمُ ٱلْبَيِّنَـٰتُ بَغْيًۢا بَيْنَهُمْ ۖ فَهَدَى ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ لِمَا ٱخْتَلَفُوا۟ فِيهِ مِنَ ٱلْحَقِّ بِإِذْنِهِۦ ۗ وَٱللَّهُ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"Mankind was [of] one religion [before their deviation]; then Allāh sent the prophets as bringers of good tidings and warners and sent down with them the Scripture in truth to judge between the people concerning that in which they differed. And none differed over it [i.e., the Scripture] except those who were given it - after the clear proofs came to them - out of jealous animosity among themselves. And Allāh guided those who believed to the truth concerning that over which they had differed, by His permission. And Allāh guides whom He wills to a straight path.","tr":"Kana annasu ommatan wahidatanfabaAAatha Allahu annabiyyeena mubashshireenawamunthireena waanzala maAAahumu alkitaba bilhaqqiliyahkuma bayna annasi feemaikhtalafoo feehi wama ikhtalafa feehi illa allatheenaootoohu min baAAdi ma jaat-humu albayyinatubaghyan baynahum fahada Allahu allatheena amanoolima ikhtalafoo feehi mina alhaqqi bi-ithnihiwallahu yahdee man yashao ila siratinmustaqeem","juz":2,"page":33},{"s":2,"a":214,"key":"2:214","ar":"أَمْ حَسِبْتُمْ أَن تَدْخُلُوا۟ ٱلْجَنَّةَ وَلَمَّا يَأْتِكُم مَّثَلُ ٱلَّذِينَ خَلَوْا۟ مِن قَبْلِكُم ۖ مَّسَّتْهُمُ ٱلْبَأْسَآءُ وَٱلضَّرَّآءُ وَزُلْزِلُوا۟ حَتَّىٰ يَقُولَ ٱلرَّسُولُ وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ مَتَىٰ نَصْرُ ٱللَّهِ ۗ أَلَآ إِنَّ نَصْرَ ٱللَّهِ قَرِيبٌ","en":"Or do you think that you will enter Paradise while such [trial] has not yet come to you as came to those who passed on before you? They were touched by poverty and hardship and were shaken until [even their] messenger and those who believed with him said, \"When is the help of Allāh?\" Unquestionably, the help of Allāh is near.","tr":"Am hasibtum an tadkhuloo aljannatawalamma ya/tikum mathalu allatheena khalaw minqablikum massat-humu alba/sao waddarraowazulziloo hatta yaqoola arrasoolu wallatheenaamanoo maAAahu mata nasru Allahi alainna nasra Allahi qareeb","juz":2,"page":33},{"s":2,"a":215,"key":"2:215","ar":"يَسْـَٔلُونَكَ مَاذَا يُنفِقُونَ ۖ قُلْ مَآ أَنفَقْتُم مِّنْ خَيْرٍ فَلِلْوَٰلِدَيْنِ وَٱلْأَقْرَبِينَ وَٱلْيَتَـٰمَىٰ وَٱلْمَسَـٰكِينِ وَٱبْنِ ٱلسَّبِيلِ ۗ وَمَا تَفْعَلُوا۟ مِنْ خَيْرٍ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌ","en":"They ask you, [O Muḥammad], what they should spend. Say, \"Whatever you spend of good is [to be] for parents and relatives and orphans and the needy and the traveler. And whatever you do of good - indeed, Allāh is Knowing of it.\"","tr":"Yas-aloonaka matha yunfiqoona qul maanfaqtum min khayrin falilwalidayni wal-aqrabeenawalyatama walmasakeeni wabniassabeeli wama tafAAaloo min khayrin fa-inna Allahabihi AAaleem","juz":2,"page":33},{"s":2,"a":216,"key":"2:216","ar":"كُتِبَ عَلَيْكُمُ ٱلْقِتَالُ وَهُوَ كُرْهٌ لَّكُمْ ۖ وَعَسَىٰٓ أَن تَكْرَهُوا۟ شَيْـًٔا وَهُوَ خَيْرٌ لَّكُمْ ۖ وَعَسَىٰٓ أَن تُحِبُّوا۟ شَيْـًٔا وَهُوَ شَرٌّ لَّكُمْ ۗ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ","en":"Battle has been enjoined upon you while it is hateful to you. But perhaps you hate a thing and it is good for you; and perhaps you love a thing and it is bad for you. And Allāh knows, while you know not.","tr":"Kutiba AAalaykumu alqitalu wahuwakurhun lakum waAAasa an takrahoo shay-an wahuwa khayrunlakum waAAasa an tuhibboo shay-an wahuwa sharrunlakum wallahu yaAAlamu waantum lataAAlamoon","juz":2,"page":34},{"s":2,"a":217,"key":"2:217","ar":"يَسْـَٔلُونَكَ عَنِ ٱلشَّهْرِ ٱلْحَرَامِ قِتَالٍ فِيهِ ۖ قُلْ قِتَالٌ فِيهِ كَبِيرٌ ۖ وَصَدٌّ عَن سَبِيلِ ٱللَّهِ وَكُفْرٌۢ بِهِۦ وَٱلْمَسْجِدِ ٱلْحَرَامِ وَإِخْرَاجُ أَهْلِهِۦ مِنْهُ أَكْبَرُ عِندَ ٱللَّهِ ۚ وَٱلْفِتْنَةُ أَكْبَرُ مِنَ ٱلْقَتْلِ ۗ وَلَا يَزَالُونَ يُقَـٰتِلُونَكُمْ حَتَّىٰ يَرُدُّوكُمْ عَن دِينِكُمْ إِنِ ٱسْتَطَـٰعُوا۟ ۚ وَمَن يَرْتَدِدْ مِنكُمْ عَن دِينِهِۦ فَيَمُتْ وَهُوَ كَافِرٌ فَأُو۟لَـٰٓئِكَ حَبِطَتْ أَعْمَـٰلُهُمْ فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ ۖ وَأُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"They ask you about the sacred month1 - about fighting therein. Say, \"Fighting therein is great [sin], but averting [people] from the way of Allāh and disbelief in Him and [preventing access to] al-Masjid al-Ḥarām and the expulsion of its people therefrom are greater [evil] in the sight of Allāh. And fitnah2 is greater than killing.\" And they will continue to fight you until they turn you back from your religion if they are able. And whoever of you reverts from his religion [to disbelief] and dies while he is a disbeliever - for those, their deeds have become worthless in this world and the Hereafter, and those are the companions of the Fire; they will abide therein eternally.","tr":"Yas-aloonaka AAani ashshahri alharamiqitalin feehi qul qitalun feehi kabeerun wasaddunAAan sabeeli Allahi wakufrun bihi walmasjidi alharamiwa-ikhraju ahlihi minhu akbaru AAinda Allahi walfitnatuakbaru mina alqatli wala yazaloona yuqatiloonakumhatta yaruddookum AAan deenikum ini istataAAoowaman yartadid minkum AAan deenihi fayamut wahuwa kafirunfaola-ika habitat aAAmaluhum fee addunyawal-akhirati waola-ika as-habuannari hum feeha khalidoon","juz":2,"page":34},{"s":2,"a":218,"key":"2:218","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَاجَرُوا۟ وَجَـٰهَدُوا۟ فِى سَبِيلِ ٱللَّهِ أُو۟لَـٰٓئِكَ يَرْجُونَ رَحْمَتَ ٱللَّهِ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"Indeed, those who have believed and those who have emigrated and fought in the cause of Allāh - those expect the mercy of Allāh. And Allāh is Forgiving and Merciful.","tr":"Inna allatheena amanoo wallatheenahajaroo wajahadoo fee sabeeli Allahi ola-ikayarjoona rahmata Allahi wallahughafoorun raheem","juz":2,"page":34},{"s":2,"a":219,"key":"2:219","ar":"۞ يَسْـَٔلُونَكَ عَنِ ٱلْخَمْرِ وَٱلْمَيْسِرِ ۖ قُلْ فِيهِمَآ إِثْمٌ كَبِيرٌ وَمَنَـٰفِعُ لِلنَّاسِ وَإِثْمُهُمَآ أَكْبَرُ مِن نَّفْعِهِمَا ۗ وَيَسْـَٔلُونَكَ مَاذَا يُنفِقُونَ قُلِ ٱلْعَفْوَ ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْـَٔايَـٰتِ لَعَلَّكُمْ تَتَفَكَّرُونَ","en":"They ask you about wine1 and gambling. Say, \"In them is great sin and [yet, some] benefit for people. But their sin is greater than their benefit.\" And they ask you what they should spend. Say, \"The excess [beyond needs].\" Thus Allāh makes clear to you the verses [of revelation] that you might give thought","tr":"Yas-aloonaka AAani alkhamri walmaysiriqul feehima ithmun kabeerun wamanafiAAu linnasiwa-ithmuhuma akbaru min nafAAihima wayas-aloonaka mathayunfiqoona quli alAAafwa kathalika yubayyinu Allahulakumu al-ayati laAAallakum tatafakkaroon","juz":2,"page":34},{"s":2,"a":220,"key":"2:220","ar":"فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ ۗ وَيَسْـَٔلُونَكَ عَنِ ٱلْيَتَـٰمَىٰ ۖ قُلْ إِصْلَاحٌ لَّهُمْ خَيْرٌ ۖ وَإِن تُخَالِطُوهُمْ فَإِخْوَٰنُكُمْ ۚ وَٱللَّهُ يَعْلَمُ ٱلْمُفْسِدَ مِنَ ٱلْمُصْلِحِ ۚ وَلَوْ شَآءَ ٱللَّهُ لَأَعْنَتَكُمْ ۚ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ","en":"To this world and the Hereafter. And they ask you about orphans. Say, \"Improvement for them is best. And if you mix your affairs with theirs - they are your brothers. And Allāh knows the corrupter from the amender. And if Allāh had willed, He could have put you in difficulty. Indeed, Allāh is Exalted in Might and Wise.\"","tr":"Fee addunya wal-akhiratiwayas-aloonaka AAani alyatama qul islahunlahum khayrun wa-in tukhalitoohum fa-ikhwanukumwallahu yaAAlamu almufsida mina almuslihiwalaw shaa Allahu laaAAnatakum inna AllahaAAazeezun hakeem","juz":2,"page":35},{"s":2,"a":221,"key":"2:221","ar":"وَلَا تَنكِحُوا۟ ٱلْمُشْرِكَـٰتِ حَتَّىٰ يُؤْمِنَّ ۚ وَلَأَمَةٌ مُّؤْمِنَةٌ خَيْرٌ مِّن مُّشْرِكَةٍ وَلَوْ أَعْجَبَتْكُمْ ۗ وَلَا تُنكِحُوا۟ ٱلْمُشْرِكِينَ حَتَّىٰ يُؤْمِنُوا۟ ۚ وَلَعَبْدٌ مُّؤْمِنٌ خَيْرٌ مِّن مُّشْرِكٍ وَلَوْ أَعْجَبَكُمْ ۗ أُو۟لَـٰٓئِكَ يَدْعُونَ إِلَى ٱلنَّارِ ۖ وَٱللَّهُ يَدْعُوٓا۟ إِلَى ٱلْجَنَّةِ وَٱلْمَغْفِرَةِ بِإِذْنِهِۦ ۖ وَيُبَيِّنُ ءَايَـٰتِهِۦ لِلنَّاسِ لَعَلَّهُمْ يَتَذَكَّرُونَ","en":"And do not marry polytheistic women until they believe.1 And a believing slave woman is better than a polytheist, even though she might please you. And do not marry polytheistic men [to your women] until they believe. And a believing slave is better than a polytheist, even though he might please you. Those invite [you] to the Fire, but Allāh invites to Paradise and to forgiveness, by His permission. And He makes clear His verses [i.e., ordinances] to the people that perhaps they may remember.","tr":"Wala tankihoo almushrikatihatta yu/minna walaamatun mu/minatun khayrun minmushrikatin walaw aAAjabatkum wala tunkihooalmushrikeena hatta yu/minoo walaAAabdun mu/minunkhayrun min mushrikin walaw aAAjabakum ola-ika yadAAoonaila annari wallahu yadAAooila aljannati walmaghfirati bi-ithnihiwayubayyinu ayatihi linnasilaAAallahum yatathakkaroon","juz":2,"page":35},{"s":2,"a":222,"key":"2:222","ar":"وَيَسْـَٔلُونَكَ عَنِ ٱلْمَحِيضِ ۖ قُلْ هُوَ أَذًى فَٱعْتَزِلُوا۟ ٱلنِّسَآءَ فِى ٱلْمَحِيضِ ۖ وَلَا تَقْرَبُوهُنَّ حَتَّىٰ يَطْهُرْنَ ۖ فَإِذَا تَطَهَّرْنَ فَأْتُوهُنَّ مِنْ حَيْثُ أَمَرَكُمُ ٱللَّهُ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلتَّوَّٰبِينَ وَيُحِبُّ ٱلْمُتَطَهِّرِينَ","en":"And they ask you about menstruation. Say, \"It is harm, so keep away from wives1 during menstruation. And do not approach them until they are pure. And when they have purified themselves,2 then come to them from where Allāh has ordained for you. Indeed, Allāh loves those who are constantly repentant and loves those who purify themselves.\"","tr":"Wayas-aloonaka AAani almaheediqul huwa athan faAAtaziloo annisaafee almaheedi wala taqraboohunna hattayathurna fa-itha tatahharna fa/toohunna min haythuamarakumu Allahu inna Allaha yuhibbu attawwabeenawayuhibbu almutatahhireen","juz":2,"page":35},{"s":2,"a":223,"key":"2:223","ar":"نِسَآؤُكُمْ حَرْثٌ لَّكُمْ فَأْتُوا۟ حَرْثَكُمْ أَنَّىٰ شِئْتُمْ ۖ وَقَدِّمُوا۟ لِأَنفُسِكُمْ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّكُم مُّلَـٰقُوهُ ۗ وَبَشِّرِ ٱلْمُؤْمِنِينَ","en":"Your wives are a place of cultivation [i.e., sowing of seed] for you, so come to your place of cultivation however you wish and put forth [righteousness] for yourselves. And fear Allāh and know that you will meet Him. And give good tidings to the believers.","tr":"Nisaokum harthun lakum fa/tooharthakum anna shi/tum waqaddimoo li-anfusikum wattaqooAllaha waAAlamoo annakum mulaqoohuwabashshiri almu/mineen","juz":2,"page":35},{"s":2,"a":224,"key":"2:224","ar":"وَلَا تَجْعَلُوا۟ ٱللَّهَ عُرْضَةً لِّأَيْمَـٰنِكُمْ أَن تَبَرُّوا۟ وَتَتَّقُوا۟ وَتُصْلِحُوا۟ بَيْنَ ٱلنَّاسِ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ","en":"And do not make [your oath by] Allāh an excuse against being righteous and fearing Allāh and making peace among people. And Allāh is Hearing and Knowing.","tr":"Wala tajAAaloo Allaha AAurdatanli-aymanikum an tabarroo watattaqoo watuslihoobayna annasi wallahu sameeAAunAAaleem","juz":2,"page":35},{"s":2,"a":225,"key":"2:225","ar":"لَّا يُؤَاخِذُكُمُ ٱللَّهُ بِٱللَّغْوِ فِىٓ أَيْمَـٰنِكُمْ وَلَـٰكِن يُؤَاخِذُكُم بِمَا كَسَبَتْ قُلُوبُكُمْ ۗ وَٱللَّهُ غَفُورٌ حَلِيمٌ","en":"Allāh does not impose blame upon you for what is unintentional in your oaths, but He imposes blame upon you for what your hearts have earned. And Allāh is Forgiving and Forbearing.1","tr":"La yu-akhithukumu Allahubillaghwi fee aymanikum walakin yu-akhithukumbima kasabat quloobukum wallahu ghafoorun haleem","juz":2,"page":36},{"s":2,"a":226,"key":"2:226","ar":"لِّلَّذِينَ يُؤْلُونَ مِن نِّسَآئِهِمْ تَرَبُّصُ أَرْبَعَةِ أَشْهُرٍ ۖ فَإِن فَآءُو فَإِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"For those who swear not to have sexual relations with their wives1 is a waiting time of four months, but if they return [to normal relations] - then indeed, Allāh is Forgiving and Merciful.","tr":"Lillatheena yu/loona min nisa-ihimtarabbusu arbaAAati ashhurin fa-in faoo fa-inna Allahaghafoorun raheem","juz":2,"page":36},{"s":2,"a":227,"key":"2:227","ar":"وَإِنْ عَزَمُوا۟ ٱلطَّلَـٰقَ فَإِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌ","en":"And if they decide on divorce - then indeed, Allāh is Hearing and Knowing.","tr":"Wa-in AAazamoo attalaqafa-inna Allaha sameeAAun AAaleem","juz":2,"page":36},{"s":2,"a":228,"key":"2:228","ar":"وَٱلْمُطَلَّقَـٰتُ يَتَرَبَّصْنَ بِأَنفُسِهِنَّ ثَلَـٰثَةَ قُرُوٓءٍ ۚ وَلَا يَحِلُّ لَهُنَّ أَن يَكْتُمْنَ مَا خَلَقَ ٱللَّهُ فِىٓ أَرْحَامِهِنَّ إِن كُنَّ يُؤْمِنَّ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ ۚ وَبُعُولَتُهُنَّ أَحَقُّ بِرَدِّهِنَّ فِى ذَٰلِكَ إِنْ أَرَادُوٓا۟ إِصْلَـٰحًا ۚ وَلَهُنَّ مِثْلُ ٱلَّذِى عَلَيْهِنَّ بِٱلْمَعْرُوفِ ۚ وَلِلرِّجَالِ عَلَيْهِنَّ دَرَجَةٌ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ","en":"Divorced women remain in waiting [i.e., do not remarry] for three periods,1 and it is not lawful for them to conceal what Allāh has created in their wombs if they believe in Allāh and the Last Day. And their husbands have more right to take them back in this [period] if they want reconciliation.2 And due to them [i.e., the wives] is similar to what is expected of them, according to what is reasonable.3 But the men [i.e., husbands] have a degree over them [in responsibility and authority]. And Allāh is Exalted in Might and Wise.","tr":"Walmutallaqatuyatarabbasna bi-anfusihinna thalathata quroo-in walayahillu lahunna an yaktumna ma khalaqa Allahufee arhamihinna in kunna yu/minna billahiwalyawmi al-akhiri wabuAAoolatuhunna ahaqqubiraddihinna fee thalika in aradoo islahanwalahunna mithlu allathee AAalayhinna bilmaAAroofiwalirrijali AAalayhinna darajatun wallahuAAazeezun hakeem","juz":2,"page":36},{"s":2,"a":229,"key":"2:229","ar":"ٱلطَّلَـٰقُ مَرَّتَانِ ۖ فَإِمْسَاكٌۢ بِمَعْرُوفٍ أَوْ تَسْرِيحٌۢ بِإِحْسَـٰنٍ ۗ وَلَا يَحِلُّ لَكُمْ أَن تَأْخُذُوا۟ مِمَّآ ءَاتَيْتُمُوهُنَّ شَيْـًٔا إِلَّآ أَن يَخَافَآ أَلَّا يُقِيمَا حُدُودَ ٱللَّهِ ۖ فَإِنْ خِفْتُمْ أَلَّا يُقِيمَا حُدُودَ ٱللَّهِ فَلَا جُنَاحَ عَلَيْهِمَا فِيمَا ٱفْتَدَتْ بِهِۦ ۗ تِلْكَ حُدُودُ ٱللَّهِ فَلَا تَعْتَدُوهَا ۚ وَمَن يَتَعَدَّ حُدُودَ ٱللَّهِ فَأُو۟لَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ","en":"Divorce is twice. Then [after that], either keep [her] in an acceptable manner or release [her] with good treatment. And it is not lawful for you to take anything of what you have given them unless both fear that they will not be able to keep [within] the limits of Allāh.1 But if you fear that they will not keep [within] the limits of Allāh, then there is no blame upon either of them concerning that by which she ransoms herself. These are the limits of Allāh, so do not transgress them. And whoever transgresses the limits of Allāh - it is those who are the wrongdoers [i.e., the unjust].","tr":"Attalaqu marratanifa-imsakun bimaAAroofin aw tasreehun bi-ihsaninwala yahillu lakum an ta/khuthoo mimmaataytumoohunna shay-an illa an yakhafaalla yuqeema hudooda Allahi fa-inkhiftum alla yuqeema hudooda Allahifala junaha AAalayhima feema iftadatbihi tilka hudoodu Allahi fala taAAtadoohawaman yataAAadda hudooda Allahi faola-ikahumu aththalimoon","juz":2,"page":36},{"s":2,"a":230,"key":"2:230","ar":"فَإِن طَلَّقَهَا فَلَا تَحِلُّ لَهُۥ مِنۢ بَعْدُ حَتَّىٰ تَنكِحَ زَوْجًا غَيْرَهُۥ ۗ فَإِن طَلَّقَهَا فَلَا جُنَاحَ عَلَيْهِمَآ أَن يَتَرَاجَعَآ إِن ظَنَّآ أَن يُقِيمَا حُدُودَ ٱللَّهِ ۗ وَتِلْكَ حُدُودُ ٱللَّهِ يُبَيِّنُهَا لِقَوْمٍ يَعْلَمُونَ","en":"And if he has divorced her [for the third time], then she is not lawful to him afterward until [after] she marries a husband other than him.1 And if he [i.e., the latter husband] divorces her [or dies], there is no blame upon them [i.e., the woman and her former husband] for returning to each other if they think that they can keep [within] the limits of Allāh. These are the limits of Allāh, which He makes clear to a people who know [i.e.,understand].","tr":"Fa-in tallaqaha falatahillu lahu min baAAdu hatta tankihazawjan ghayrahu fa-in tallaqaha fala junahaAAalayhima an yatarajaAAa in thannaan yuqeema hudooda Allahi watilka hudooduAllahi yubayyinuha liqawmin yaAAlamoon","juz":2,"page":36},{"s":2,"a":231,"key":"2:231","ar":"وَإِذَا طَلَّقْتُمُ ٱلنِّسَآءَ فَبَلَغْنَ أَجَلَهُنَّ فَأَمْسِكُوهُنَّ بِمَعْرُوفٍ أَوْ سَرِّحُوهُنَّ بِمَعْرُوفٍ ۚ وَلَا تُمْسِكُوهُنَّ ضِرَارًا لِّتَعْتَدُوا۟ ۚ وَمَن يَفْعَلْ ذَٰلِكَ فَقَدْ ظَلَمَ نَفْسَهُۥ ۚ وَلَا تَتَّخِذُوٓا۟ ءَايَـٰتِ ٱللَّهِ هُزُوًا ۚ وَٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ وَمَآ أَنزَلَ عَلَيْكُم مِّنَ ٱلْكِتَـٰبِ وَٱلْحِكْمَةِ يَعِظُكُم بِهِۦ ۚ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"And when you divorce women and they have [nearly] fulfilled their term, either retain them according to acceptable terms or release them according to acceptable terms, and do not keep them, intending harm, to transgress [against them]. And whoever does that has certainly wronged himself. And do not take the verses of Allāh in jest. And remember the favor of Allāh upon you and what has been revealed to you of the Book [i.e., the Qur’ān] and wisdom [i.e., the Prophet's sunnah] by which He instructs you. And fear Allāh and know that Allāh is Knowing of all things.","tr":"Wa-itha tallaqtumu annisaafabalaghna ajalahunna faamsikoohunna bimaAAroofin aw sarrihoohunnabimaAAroofin wala tumsikoohunna diraranlitaAAtadoo waman yafAAal thalika faqad thalamanafsahu wala tattakhithoo ayati Allahihuzuwan wathkuroo niAAmata Allahi AAalaykumwama anzala AAalaykum mina alkitabi walhikmatiyaAAithukum bihi wattaqoo Allaha waAAlamooanna Allaha bikulli shay-in AAaleem","juz":2,"page":37},{"s":2,"a":232,"key":"2:232","ar":"وَإِذَا طَلَّقْتُمُ ٱلنِّسَآءَ فَبَلَغْنَ أَجَلَهُنَّ فَلَا تَعْضُلُوهُنَّ أَن يَنكِحْنَ أَزْوَٰجَهُنَّ إِذَا تَرَٰضَوْا۟ بَيْنَهُم بِٱلْمَعْرُوفِ ۗ ذَٰلِكَ يُوعَظُ بِهِۦ مَن كَانَ مِنكُمْ يُؤْمِنُ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ ۗ ذَٰلِكُمْ أَزْكَىٰ لَكُمْ وَأَطْهَرُ ۗ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ","en":"And when you divorce women1 and they have fulfilled their term, do not prevent them from remarrying their [former] husbands if they [i.e., all parties] agree among themselves on an acceptable basis. That is instructed to whoever of you believes in Allāh and the Last Day. That is better for you and purer, and Allāh knows and you know not.","tr":"Wa-itha tallaqtumu annisaafabalaghna ajalahunna fala taAAduloohunna an yankihnaazwajahunna itha taradaw baynahum bilmaAAroofithalika yooAAathu bihi man kanaminkum yu/minu billahi walyawmi al-akhirithalikum azka lakum waatharu wallahuyaAAlamu waantum la taAAlamoon","juz":2,"page":37},{"s":2,"a":233,"key":"2:233","ar":"۞ وَٱلْوَٰلِدَٰتُ يُرْضِعْنَ أَوْلَـٰدَهُنَّ حَوْلَيْنِ كَامِلَيْنِ ۖ لِمَنْ أَرَادَ أَن يُتِمَّ ٱلرَّضَاعَةَ ۚ وَعَلَى ٱلْمَوْلُودِ لَهُۥ رِزْقُهُنَّ وَكِسْوَتُهُنَّ بِٱلْمَعْرُوفِ ۚ لَا تُكَلَّفُ نَفْسٌ إِلَّا وُسْعَهَا ۚ لَا تُضَآرَّ وَٰلِدَةٌۢ بِوَلَدِهَا وَلَا مَوْلُودٌ لَّهُۥ بِوَلَدِهِۦ ۚ وَعَلَى ٱلْوَارِثِ مِثْلُ ذَٰلِكَ ۗ فَإِنْ أَرَادَا فِصَالًا عَن تَرَاضٍ مِّنْهُمَا وَتَشَاوُرٍ فَلَا جُنَاحَ عَلَيْهِمَا ۗ وَإِنْ أَرَدتُّمْ أَن تَسْتَرْضِعُوٓا۟ أَوْلَـٰدَكُمْ فَلَا جُنَاحَ عَلَيْكُمْ إِذَا سَلَّمْتُم مَّآ ءَاتَيْتُم بِٱلْمَعْرُوفِ ۗ وَٱتَّقُوا۟ ٱللَّهَ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"Mothers may nurse [i.e., breastfeed] their children two complete years for whoever wishes to complete the nursing [period]. Upon the father is their [i.e., the mothers'] provision and their clothing according to what is acceptable. No person is charged with more than his capacity. No mother should be harmed through her child, and no father through his child. And upon the [father's] heir is [a duty] like that [of the father]. And if they both desire weaning through mutual consent from both of them and consultation, there is no blame upon either of them. And if you wish to have your children nursed by a substitute, there is no blame upon you as long as you give payment according to what is acceptable. And fear Allāh and know that Allāh is Seeing of what you do.","tr":"Walwalidatu yurdiAAnaawladahunna hawlayni kamilayni liman aradaan yutimma arradaAAata waAAala almawloodilahu rizquhunna wakiswatuhunna bilmaAAroofi latukallafu nafsun illa wusAAaha la tudarrawalidatun biwaladiha wala mawloodun lahubiwaladihi waAAala alwarithi mithlu thalikafa-in arada fisalan AAan taradinminhuma watashawurin fala junahaAAalayhima wa-in aradtum an tastardiAAoo awladakumfala junaha AAalaykum itha sallamtum maataytum bilmaAAroofi wattaqoo AllahawaAAlamoo anna Allaha bima taAAmaloona baseer","juz":2,"page":37},{"s":2,"a":234,"key":"2:234","ar":"وَٱلَّذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَٰجًا يَتَرَبَّصْنَ بِأَنفُسِهِنَّ أَرْبَعَةَ أَشْهُرٍ وَعَشْرًا ۖ فَإِذَا بَلَغْنَ أَجَلَهُنَّ فَلَا جُنَاحَ عَلَيْكُمْ فِيمَا فَعَلْنَ فِىٓ أَنفُسِهِنَّ بِٱلْمَعْرُوفِ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌ","en":"And those who are taken in death among you and leave wives behind - they, [the wives, shall] wait four months and ten [days]. And when they have fulfilled their term, then there is no blame upon you for what they do with themselves in an acceptable manner.1 And Allāh is [fully] Aware of what you do.","tr":"Wallatheena yutawaffawnaminkum wayatharoona azwajan yatarabbasnabi-anfusihinna arbaAAata ashhurin waAAashran fa-ithabalaghna ajalahunna fala junaha AAalaykum feemafaAAalna fee anfusihinna bilmaAAroofi wallahubima taAAmaloona khabeer","juz":2,"page":38},{"s":2,"a":235,"key":"2:235","ar":"وَلَا جُنَاحَ عَلَيْكُمْ فِيمَا عَرَّضْتُم بِهِۦ مِنْ خِطْبَةِ ٱلنِّسَآءِ أَوْ أَكْنَنتُمْ فِىٓ أَنفُسِكُمْ ۚ عَلِمَ ٱللَّهُ أَنَّكُمْ سَتَذْكُرُونَهُنَّ وَلَـٰكِن لَّا تُوَاعِدُوهُنَّ سِرًّا إِلَّآ أَن تَقُولُوا۟ قَوْلًا مَّعْرُوفًا ۚ وَلَا تَعْزِمُوا۟ عُقْدَةَ ٱلنِّكَاحِ حَتَّىٰ يَبْلُغَ ٱلْكِتَـٰبُ أَجَلَهُۥ ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ يَعْلَمُ مَا فِىٓ أَنفُسِكُمْ فَٱحْذَرُوهُ ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ غَفُورٌ حَلِيمٌ","en":"There is no blame upon you for that to which you [indirectly] allude concerning a proposal to women or for what you conceal within yourselves. Allāh knows that you will have them in mind. But do not promise them secretly except for saying a proper saying. And do not determine to undertake a marriage contract until the decreed period1 reaches its end. And know that Allāh knows what is within yourselves, so beware of Him. And know that Allāh is Forgiving and Forbearing.","tr":"Wala junaha AAalaykum feemaAAarradtum bihi min khitbati annisa-iaw aknantum fee anfusikum AAalima Allahu annakum satathkuroonahunnawalakin la tuwaAAidoohunna sirran illaan taqooloo qawlan maAAroofan wala taAAzimoo AAuqdata annikahihatta yablugha alkitabu ajalahu waAAlamooanna Allaha yaAAlamu ma fee anfusikum fahtharoohuwaAAlamoo anna Allaha ghafoorun haleem","juz":2,"page":38},{"s":2,"a":236,"key":"2:236","ar":"لَّا جُنَاحَ عَلَيْكُمْ إِن طَلَّقْتُمُ ٱلنِّسَآءَ مَا لَمْ تَمَسُّوهُنَّ أَوْ تَفْرِضُوا۟ لَهُنَّ فَرِيضَةً ۚ وَمَتِّعُوهُنَّ عَلَى ٱلْمُوسِعِ قَدَرُهُۥ وَعَلَى ٱلْمُقْتِرِ قَدَرُهُۥ مَتَـٰعًۢا بِٱلْمَعْرُوفِ ۖ حَقًّا عَلَى ٱلْمُحْسِنِينَ","en":"There is no blame upon you if you divorce women you have not touched1 nor specified for them an obligation.2 But give them [a gift of] compensation - the wealthy according to his capability and the poor according to his capability - a provision according to what is acceptable, a duty upon the doers of good.","tr":"La junaha AAalaykum in tallaqtumuannisaa ma lam tamassoohunna aw tafridoolahunna fareedatan wamattiAAoohunna AAalaalmoosiAAi qadaruhu waAAala almuqtiri qadaruhu mataAAanbilmaAAroofi haqqan AAala almuhsineen","juz":2,"page":38},{"s":2,"a":237,"key":"2:237","ar":"وَإِن طَلَّقْتُمُوهُنَّ مِن قَبْلِ أَن تَمَسُّوهُنَّ وَقَدْ فَرَضْتُمْ لَهُنَّ فَرِيضَةً فَنِصْفُ مَا فَرَضْتُمْ إِلَّآ أَن يَعْفُونَ أَوْ يَعْفُوَا۟ ٱلَّذِى بِيَدِهِۦ عُقْدَةُ ٱلنِّكَاحِ ۚ وَأَن تَعْفُوٓا۟ أَقْرَبُ لِلتَّقْوَىٰ ۚ وَلَا تَنسَوُا۟ ٱلْفَضْلَ بَيْنَكُمْ ۚ إِنَّ ٱللَّهَ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"And if you divorce them before you have touched them and you have already specified for them an obligation, then [give] half of what you specified - unless they forego the right or the one in whose hand is the marriage contract foregoes it. And to forego it is nearer to righteousness. And do not forget graciousness between you. Indeed Allāh, of whatever you do, is Seeing.","tr":"Wa-in tallaqtumoohunna min qabli antamassoohunna waqad faradtum lahunna fareedatanfanisfu ma faradtum illa an yaAAfoonaaw yaAAfuwa allathee biyadihi AAuqdatu annikahiwaan taAAfoo aqrabu littaqwa wala tansawooalfadla baynakum inna Allaha bimataAAmaloona baseer","juz":2,"page":38},{"s":2,"a":238,"key":"2:238","ar":"حَـٰفِظُوا۟ عَلَى ٱلصَّلَوَٰتِ وَٱلصَّلَوٰةِ ٱلْوُسْطَىٰ وَقُومُوا۟ لِلَّهِ قَـٰنِتِينَ","en":"Maintain with care the [obligatory] prayers and [in particular] the middle [i.e., ʿaṣr] prayer and stand before Allāh, devoutly obedient.","tr":"Hafithoo AAalaassalawati wassalatialwusta waqoomoo lillahi qaniteen","juz":2,"page":39},{"s":2,"a":239,"key":"2:239","ar":"فَإِنْ خِفْتُمْ فَرِجَالًا أَوْ رُكْبَانًا ۖ فَإِذَآ أَمِنتُمْ فَٱذْكُرُوا۟ ٱللَّهَ كَمَا عَلَّمَكُم مَّا لَمْ تَكُونُوا۟ تَعْلَمُونَ","en":"And if you fear [an enemy, then pray] on foot or riding. But when you are secure, then remember Allāh [in prayer], as He has taught you that which you did not [previously] know.","tr":"Fa-in khiftum farijalan aw rukbananfa-itha amintum fathkuroo Allaha kamaAAallamakum ma lam takoonoo taAAlamoon","juz":2,"page":39},{"s":2,"a":240,"key":"2:240","ar":"وَٱلَّذِينَ يُتَوَفَّوْنَ مِنكُمْ وَيَذَرُونَ أَزْوَٰجًا وَصِيَّةً لِّأَزْوَٰجِهِم مَّتَـٰعًا إِلَى ٱلْحَوْلِ غَيْرَ إِخْرَاجٍ ۚ فَإِنْ خَرَجْنَ فَلَا جُنَاحَ عَلَيْكُمْ فِى مَا فَعَلْنَ فِىٓ أَنفُسِهِنَّ مِن مَّعْرُوفٍ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ","en":"And those who are taken in death among you and leave wives behind - for their wives is a bequest: maintenance for one year without turning [them] out. But if they leave [of their own accord], then there is no blame upon you for what they do with themselves in an acceptable way.1 And Allāh is Exalted in Might and Wise.","tr":"Wallatheena yutawaffawnaminkum wayatharoona azwajan wasiyyatanli-azwajihim mataAAan ila alhawlighayra ikhrajin fa-in kharajna fala junahaAAalaykum fee ma faAAalna fee anfusihinna min maAAroofinwallahu AAazeezun hakeem","juz":2,"page":39},{"s":2,"a":241,"key":"2:241","ar":"وَلِلْمُطَلَّقَـٰتِ مَتَـٰعٌۢ بِٱلْمَعْرُوفِ ۖ حَقًّا عَلَى ٱلْمُتَّقِينَ","en":"And for divorced women is a provision according to what is acceptable - a duty upon the righteous.","tr":"Walilmutallaqati mataAAunbilmaAAroofi haqqan AAala almuttaqeen","juz":2,"page":39},{"s":2,"a":242,"key":"2:242","ar":"كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَـٰتِهِۦ لَعَلَّكُمْ تَعْقِلُونَ","en":"Thus does Allāh make clear to you His verses [i.e., laws] that you might use reason.","tr":"Kathalika yubayyinu Allahulakum ayatihi laAAallakum taAAqiloon","juz":2,"page":39},{"s":2,"a":243,"key":"2:243","ar":"۞ أَلَمْ تَرَ إِلَى ٱلَّذِينَ خَرَجُوا۟ مِن دِيَـٰرِهِمْ وَهُمْ أُلُوفٌ حَذَرَ ٱلْمَوْتِ فَقَالَ لَهُمُ ٱللَّهُ مُوتُوا۟ ثُمَّ أَحْيَـٰهُمْ ۚ إِنَّ ٱللَّهَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَشْكُرُونَ","en":"Have you not considered those who left their homes in many thousands, fearing death? Allāh said to them, \"Die\"; then He restored them to life. And Allāh is the possessor of bounty for the people, but most of the people do not show gratitude.","tr":"Alam tara ila allatheenakharajoo min diyarihim wahum oloofun hatharaalmawti faqala lahumu Allahu mootoo thumma ahyahuminna Allaha lathoo fadlin AAala annasiwalakinna akthara annasi layashkuroon","juz":2,"page":39},{"s":2,"a":244,"key":"2:244","ar":"وَقَـٰتِلُوا۟ فِى سَبِيلِ ٱللَّهِ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌ","en":"And fight in the cause of Allāh and know that Allāh is Hearing and Knowing.","tr":"Waqatiloo fee sabeeli AllahiwaAAlamoo anna Allaha sameeAAun AAaleem","juz":2,"page":39},{"s":2,"a":245,"key":"2:245","ar":"مَّن ذَا ٱلَّذِى يُقْرِضُ ٱللَّهَ قَرْضًا حَسَنًا فَيُضَـٰعِفَهُۥ لَهُۥٓ أَضْعَافًا كَثِيرَةً ۚ وَٱللَّهُ يَقْبِضُ وَيَبْصُۜطُ وَإِلَيْهِ تُرْجَعُونَ","en":"Who is it that would loan Allāh a goodly loan so He may multiply it for him many times over? And it is Allāh who withholds and grants abundance, and to Him you will be returned.","tr":"Man tha allathee yuqriduAllaha qardan hasanan fayudaAAifahulahu adAAafan katheeratan wallahuyaqbidu wayabsutu wa-ilayhi turjaAAoon","juz":2,"page":39},{"s":2,"a":246,"key":"2:246","ar":"أَلَمْ تَرَ إِلَى ٱلْمَلَإِ مِنۢ بَنِىٓ إِسْرَٰٓءِيلَ مِنۢ بَعْدِ مُوسَىٰٓ إِذْ قَالُوا۟ لِنَبِىٍّ لَّهُمُ ٱبْعَثْ لَنَا مَلِكًا نُّقَـٰتِلْ فِى سَبِيلِ ٱللَّهِ ۖ قَالَ هَلْ عَسَيْتُمْ إِن كُتِبَ عَلَيْكُمُ ٱلْقِتَالُ أَلَّا تُقَـٰتِلُوا۟ ۖ قَالُوا۟ وَمَا لَنَآ أَلَّا نُقَـٰتِلَ فِى سَبِيلِ ٱللَّهِ وَقَدْ أُخْرِجْنَا مِن دِيَـٰرِنَا وَأَبْنَآئِنَا ۖ فَلَمَّا كُتِبَ عَلَيْهِمُ ٱلْقِتَالُ تَوَلَّوْا۟ إِلَّا قَلِيلًا مِّنْهُمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلظَّـٰلِمِينَ","en":"Have you not considered the assembly of the Children of Israel after [the time of] Moses when they said to a prophet of theirs, \"Send to us a king, and we will fight in the way of Allāh\"? He said, \"Would you perhaps refrain from fighting if battle was prescribed for you?\" They said, \"And why should we not fight in the cause of Allāh when we have been driven out from our homes and from our children?\" But when battle was prescribed for them, they turned away, except for a few of them. And Allāh is Knowing of the wrongdoers.","tr":"Alam tara ila almala-i min banee isra-eelamin baAAdi moosa ith qaloo linabiyyin lahumuibAAath lana malikan nuqatil fee sabeeli Allahiqala hal AAasaytum in kutiba AAalaykumu alqitalualla tuqatiloo qaloo wama lanaalla nuqatila fee sabeeli Allahi waqadokhrijna min diyarina waabna-inafalamma kutiba AAalayhimu alqitalu tawallaw illaqaleelan minhum wallahu AAaleemun biththalimeen","juz":2,"page":40},{"s":2,"a":247,"key":"2:247","ar":"وَقَالَ لَهُمْ نَبِيُّهُمْ إِنَّ ٱللَّهَ قَدْ بَعَثَ لَكُمْ طَالُوتَ مَلِكًا ۚ قَالُوٓا۟ أَنَّىٰ يَكُونُ لَهُ ٱلْمُلْكُ عَلَيْنَا وَنَحْنُ أَحَقُّ بِٱلْمُلْكِ مِنْهُ وَلَمْ يُؤْتَ سَعَةً مِّنَ ٱلْمَالِ ۚ قَالَ إِنَّ ٱللَّهَ ٱصْطَفَىٰهُ عَلَيْكُمْ وَزَادَهُۥ بَسْطَةً فِى ٱلْعِلْمِ وَٱلْجِسْمِ ۖ وَٱللَّهُ يُؤْتِى مُلْكَهُۥ مَن يَشَآءُ ۚ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ","en":"And their prophet said to them, \"Indeed, Allāh has sent to you Saul as a king.\" They said, \"How can he have kingship over us while we are more worthy of kingship than him and he has not been given any measure of wealth?\" He said, \"Indeed, Allāh has chosen him over you and has increased him abundantly in knowledge and stature. And Allāh gives His sovereignty to whom He wills. And Allāh is all-Encompassing [in favor] and Knowing.\"","tr":"Waqala lahum nabiyyuhum inna Allahaqad baAAatha lakum taloota malikan qaloo annayakoonu lahu almulku AAalayna wanahnu ahaqqubilmulki minhu walam yu/ta saAAatan mina almali qalainna Allaha istafahu AAalaykum wazadahubastatan fee alAAilmi waljismi wallahuyu/tee mulkahu man yashao wallahu wasiAAunAAaleem","juz":2,"page":40},{"s":2,"a":248,"key":"2:248","ar":"وَقَالَ لَهُمْ نَبِيُّهُمْ إِنَّ ءَايَةَ مُلْكِهِۦٓ أَن يَأْتِيَكُمُ ٱلتَّابُوتُ فِيهِ سَكِينَةٌ مِّن رَّبِّكُمْ وَبَقِيَّةٌ مِّمَّا تَرَكَ ءَالُ مُوسَىٰ وَءَالُ هَـٰرُونَ تَحْمِلُهُ ٱلْمَلَـٰٓئِكَةُ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ","en":"And their prophet said to them, \"Indeed, a sign of his kingship is that the chest will come to you in which is assurance1 from your Lord and a remnant of what the family of Moses and the family of Aaron had left, carried by the angels. Indeed in that is a sign for you, if you are believers.\"","tr":"Waqala lahum nabiyyuhum inna ayatamulkihi an ya/tiyakumu attabootu feehi sakeenatunmin rabbikum wabaqiyyatun mimma taraka alu moosawaalu haroona tahmiluhu almala-ikatuinna fee thalika laayatan lakum in kuntum mu/mineen","juz":2,"page":40},{"s":2,"a":249,"key":"2:249","ar":"فَلَمَّا فَصَلَ طَالُوتُ بِٱلْجُنُودِ قَالَ إِنَّ ٱللَّهَ مُبْتَلِيكُم بِنَهَرٍ فَمَن شَرِبَ مِنْهُ فَلَيْسَ مِنِّى وَمَن لَّمْ يَطْعَمْهُ فَإِنَّهُۥ مِنِّىٓ إِلَّا مَنِ ٱغْتَرَفَ غُرْفَةًۢ بِيَدِهِۦ ۚ فَشَرِبُوا۟ مِنْهُ إِلَّا قَلِيلًا مِّنْهُمْ ۚ فَلَمَّا جَاوَزَهُۥ هُوَ وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ قَالُوا۟ لَا طَاقَةَ لَنَا ٱلْيَوْمَ بِجَالُوتَ وَجُنُودِهِۦ ۚ قَالَ ٱلَّذِينَ يَظُنُّونَ أَنَّهُم مُّلَـٰقُوا۟ ٱللَّهِ كَم مِّن فِئَةٍ قَلِيلَةٍ غَلَبَتْ فِئَةً كَثِيرَةًۢ بِإِذْنِ ٱللَّهِ ۗ وَٱللَّهُ مَعَ ٱلصَّـٰبِرِينَ","en":"And when Saul went forth with the soldiers, he said, \"Indeed, Allāh will be testing you with a river. So whoever drinks from it is not of me, and whoever does not taste it is indeed of me, excepting one who takes [from it] in the hollow of his hand.\" But they drank from it, except a [very] few of them. Then when he had crossed it along with those who believed with him, they said, \"There is no power for us today against Goliath and his soldiers.\" But those who were certain that they would meet Allāh said, \"How many a small company has overcome a large company by permission of Allāh. And Allāh is with the patient.\"","tr":"Falamma fasala talootubiljunoodi qala inna Allaha mubtaleekumbinaharin faman shariba minhu falaysa minnee waman lam yatAAamhufa-innahu minnee illa mani ightarafa ghurfatan biyadihifashariboo minhu illa qaleelan minhum falamma jawazahuhuwa wallatheena amanoo maAAahu qaloola taqata lana alyawma bijalootawajunoodihi qala allatheena yathunnoonaannahum mulaqoo Allahi kam min fi-atin qaleelatinghalabat fi-atan katheeratan bi-ithni Allahi wallahumaAAa assabireen","juz":2,"page":41},{"s":2,"a":250,"key":"2:250","ar":"وَلَمَّا بَرَزُوا۟ لِجَالُوتَ وَجُنُودِهِۦ قَالُوا۟ رَبَّنَآ أَفْرِغْ عَلَيْنَا صَبْرًا وَثَبِّتْ أَقْدَامَنَا وَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَـٰفِرِينَ","en":"And when they went forth to [face] Goliath and his soldiers, they said, \"Our Lord, pour upon us patience and plant firmly our feet and give us victory over the disbelieving people.\"","tr":"Walamma barazoo lijalootawajunoodihi qaloo rabbana afrigh AAalayna sabranwathabbit aqdamana wansurnaAAala alqawmi alkafireen","juz":2,"page":41},{"s":2,"a":251,"key":"2:251","ar":"فَهَزَمُوهُم بِإِذْنِ ٱللَّهِ وَقَتَلَ دَاوُۥدُ جَالُوتَ وَءَاتَىٰهُ ٱللَّهُ ٱلْمُلْكَ وَٱلْحِكْمَةَ وَعَلَّمَهُۥ مِمَّا يَشَآءُ ۗ وَلَوْلَا دَفْعُ ٱللَّهِ ٱلنَّاسَ بَعْضَهُم بِبَعْضٍ لَّفَسَدَتِ ٱلْأَرْضُ وَلَـٰكِنَّ ٱللَّهَ ذُو فَضْلٍ عَلَى ٱلْعَـٰلَمِينَ","en":"So they defeated them by permission of Allāh, and David killed Goliath, and Allāh gave him the kingship and wisdom [i.e., prophethood] and taught him from that which He willed. And if it were not for Allāh checking [some] people by means of others, the earth would have been corrupted, but Allāh is the possessor of bounty for the worlds.","tr":"Fahazamoohum bi-ithni Allahiwaqatala dawoodu jaloota waatahu Allahualmulka walhikmata waAAallamahu mimma yashaowalawla dafAAu Allahi annasa baAAdahumbibaAAdin lafasadati al-ardu walakinna Allahathoo fadlin AAala alAAalameen","juz":2,"page":41},{"s":2,"a":252,"key":"2:252","ar":"تِلْكَ ءَايَـٰتُ ٱللَّهِ نَتْلُوهَا عَلَيْكَ بِٱلْحَقِّ ۚ وَإِنَّكَ لَمِنَ ٱلْمُرْسَلِينَ","en":"These are the verses of Allāh which We recite to you, [O Muḥammad], in truth. And indeed, you are from among the messengers.","tr":"Tilka ayatu Allahinatlooha AAalayka bilhaqqi wa-innaka laminaalmursaleen","juz":2,"page":41},{"s":2,"a":253,"key":"2:253","ar":"۞ تِلْكَ ٱلرُّسُلُ فَضَّلْنَا بَعْضَهُمْ عَلَىٰ بَعْضٍ ۘ مِّنْهُم مَّن كَلَّمَ ٱللَّهُ ۖ وَرَفَعَ بَعْضَهُمْ دَرَجَـٰتٍ ۚ وَءَاتَيْنَا عِيسَى ٱبْنَ مَرْيَمَ ٱلْبَيِّنَـٰتِ وَأَيَّدْنَـٰهُ بِرُوحِ ٱلْقُدُسِ ۗ وَلَوْ شَآءَ ٱللَّهُ مَا ٱقْتَتَلَ ٱلَّذِينَ مِنۢ بَعْدِهِم مِّنۢ بَعْدِ مَا جَآءَتْهُمُ ٱلْبَيِّنَـٰتُ وَلَـٰكِنِ ٱخْتَلَفُوا۟ فَمِنْهُم مَّنْ ءَامَنَ وَمِنْهُم مَّن كَفَرَ ۚ وَلَوْ شَآءَ ٱللَّهُ مَا ٱقْتَتَلُوا۟ وَلَـٰكِنَّ ٱللَّهَ يَفْعَلُ مَا يُرِيدُ","en":"Those messengers - some of them We caused to exceed others. Among them were those to whom Allāh spoke, and He raised some of them in degree. And We gave Jesus, the son of Mary, clear proofs, and We supported him with the Pure Spirit [i.e., Gabriel]. If Allāh had willed, those [generations] succeeding them would not have fought each other after the clear proofs had come to them. But they differed, and some of them believed and some of them disbelieved. And if Allāh had willed, they would not have fought each other, but Allāh does what He intends.","tr":"Tilka arrusulu faddalnabaAAdahum AAala baAAdin minhum man kallamaAllahu warafaAAa baAAdahum darajatin waataynaAAeesa ibna maryama albayyinati waayyadnahubiroohi alqudusi walaw shaa Allahu maiqtatala allatheena min baAAdihim min baAAdi ma jaat-humualbayyinatu walakini ikhtalafoo faminhum man amanawaminhum man kafara walaw shaa Allahu maiqtataloo walakinna Allaha yafAAalu mayureed","juz":3,"page":42},{"s":2,"a":254,"key":"2:254","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَنفِقُوا۟ مِمَّا رَزَقْنَـٰكُم مِّن قَبْلِ أَن يَأْتِىَ يَوْمٌ لَّا بَيْعٌ فِيهِ وَلَا خُلَّةٌ وَلَا شَفَـٰعَةٌ ۗ وَٱلْكَـٰفِرُونَ هُمُ ٱلظَّـٰلِمُونَ","en":"O you who have believed, spend from that which We have provided for you before there comes a Day in which there is no exchange [i.e., ransom] and no friendship and no intercession. And the disbelievers - they are the wrongdoers.","tr":"Ya ayyuha allatheena amanooanfiqoo mimma razaqnakum min qabli an ya/tiyayawmun la bayAAun feehi wala khullatun walashafaAAatun walkafiroona humu aththalimoon","juz":3,"page":42},{"s":2,"a":255,"key":"2:255","ar":"ٱللَّهُ لَآ إِلَـٰهَ إِلَّا هُوَ ٱلْحَىُّ ٱلْقَيُّومُ ۚ لَا تَأْخُذُهُۥ سِنَةٌ وَلَا نَوْمٌ ۚ لَّهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ مَن ذَا ٱلَّذِى يَشْفَعُ عِندَهُۥٓ إِلَّا بِإِذْنِهِۦ ۚ يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ ۖ وَلَا يُحِيطُونَ بِشَىْءٍ مِّنْ عِلْمِهِۦٓ إِلَّا بِمَا شَآءَ ۚ وَسِعَ كُرْسِيُّهُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ ۖ وَلَا يَـُٔودُهُۥ حِفْظُهُمَا ۚ وَهُوَ ٱلْعَلِىُّ ٱلْعَظِيمُ","en":"Allāh - there is no deity except Him, the Ever-Living,1 the Self-Sustaining.2 Neither drowsiness overtakes Him nor sleep. To Him belongs whatever is in the heavens and whatever is on the earth. Who is it that can intercede with Him except by His permission? He knows what is [presently] before them and what will be after them,3 and they encompass not a thing of His knowledge except for what He wills. His Kursī4 extends over the heavens and the earth, and their preservation tires Him not. And He is the Most High,5 the Most Great.6","tr":"Allahu la ilaha illahuwa alhayyu alqayyoomu la ta/khuthuhusinatun wala nawmun lahu ma fee assamawatiwama fee al-ardi man tha allatheeyashfaAAu AAindahu illa bi-ithnihi yaAAlamu mabayna aydeehim wama khalfahum wala yuheetoonabishay-in min AAilmihi illa bima shaawasiAAa kursiyyuhu assamawati wal-ardawala yaooduhu hifthuhumawahuwa alAAaliyyu alAAatheem","juz":3,"page":42},{"s":2,"a":256,"key":"2:256","ar":"لَآ إِكْرَاهَ فِى ٱلدِّينِ ۖ قَد تَّبَيَّنَ ٱلرُّشْدُ مِنَ ٱلْغَىِّ ۚ فَمَن يَكْفُرْ بِٱلطَّـٰغُوتِ وَيُؤْمِنۢ بِٱللَّهِ فَقَدِ ٱسْتَمْسَكَ بِٱلْعُرْوَةِ ٱلْوُثْقَىٰ لَا ٱنفِصَامَ لَهَا ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ","en":"There shall be no compulsion in [acceptance of] the religion. The right course has become distinct from the wrong. So whoever disbelieves in ṭāghūt1 and believes in Allāh has grasped the most trustworthy handhold with no break in it. And Allāh is Hearing and Knowing.","tr":"La ikraha fee addeeniqad tabayyana arrushdu mina alghayyi faman yakfur bittaghootiwayu/min billahi faqadi istamsaka bilAAurwatialwuthqa la infisama laha wallahusameeAAun AAaleem","juz":3,"page":42},{"s":2,"a":257,"key":"2:257","ar":"ٱللَّهُ وَلِىُّ ٱلَّذِينَ ءَامَنُوا۟ يُخْرِجُهُم مِّنَ ٱلظُّلُمَـٰتِ إِلَى ٱلنُّورِ ۖ وَٱلَّذِينَ كَفَرُوٓا۟ أَوْلِيَآؤُهُمُ ٱلطَّـٰغُوتُ يُخْرِجُونَهُم مِّنَ ٱلنُّورِ إِلَى ٱلظُّلُمَـٰتِ ۗ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"Allāh is the Ally1 of those who believe. He brings them out from darknesses into the light. And those who disbelieve - their allies are ṭāghūt. They take them out of the light into darknesses.2 Those are the companions of the Fire; they will abide eternally therein.","tr":"Allahu waliyyu allatheena amanooyukhrijuhum mina aththulumati ilaannoori wallatheena kafaroo awliyaohumuattaghootu yukhrijoonahum mina annoori ilaaththulumati ola-ika as-habuannari hum feeha khalidoon","juz":3,"page":43},{"s":2,"a":258,"key":"2:258","ar":"أَلَمْ تَرَ إِلَى ٱلَّذِى حَآجَّ إِبْرَٰهِـۧمَ فِى رَبِّهِۦٓ أَنْ ءَاتَىٰهُ ٱللَّهُ ٱلْمُلْكَ إِذْ قَالَ إِبْرَٰهِـۧمُ رَبِّىَ ٱلَّذِى يُحْىِۦ وَيُمِيتُ قَالَ أَنَا۠ أُحْىِۦ وَأُمِيتُ ۖ قَالَ إِبْرَٰهِـۧمُ فَإِنَّ ٱللَّهَ يَأْتِى بِٱلشَّمْسِ مِنَ ٱلْمَشْرِقِ فَأْتِ بِهَا مِنَ ٱلْمَغْرِبِ فَبُهِتَ ٱلَّذِى كَفَرَ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"Have you not considered the one who argued with Abraham about his Lord [merely] because Allāh had given him kingship? When Abraham said, \"My Lord is the one who gives life and causes death,\" he said, \"I give life and cause death.\" Abraham said, \"Indeed, Allāh brings up the sun from the east, so bring it up from the west.\" So the disbeliever was overwhelmed [by astonishment], and Allāh does not guide the wrongdoing people.","tr":"Alam tara ila allathee hajjaibraheema fee rabbihi an atahu Allahualmulka ith qala ibraheemu rabbiya allatheeyuhyee wayumeetu qala ana ohyeewaomeetu qala ibraheemu fa-inna Allahaya/tee bishshamsi mina almashriqi fa/ti biha minaalmaghribi fabuhita allathee kafara wallahula yahdee alqawma aththalimeen","juz":3,"page":43},{"s":2,"a":259,"key":"2:259","ar":"أَوْ كَٱلَّذِى مَرَّ عَلَىٰ قَرْيَةٍ وَهِىَ خَاوِيَةٌ عَلَىٰ عُرُوشِهَا قَالَ أَنَّىٰ يُحْىِۦ هَـٰذِهِ ٱللَّهُ بَعْدَ مَوْتِهَا ۖ فَأَمَاتَهُ ٱللَّهُ مِا۟ئَةَ عَامٍ ثُمَّ بَعَثَهُۥ ۖ قَالَ كَمْ لَبِثْتَ ۖ قَالَ لَبِثْتُ يَوْمًا أَوْ بَعْضَ يَوْمٍ ۖ قَالَ بَل لَّبِثْتَ مِا۟ئَةَ عَامٍ فَٱنظُرْ إِلَىٰ طَعَامِكَ وَشَرَابِكَ لَمْ يَتَسَنَّهْ ۖ وَٱنظُرْ إِلَىٰ حِمَارِكَ وَلِنَجْعَلَكَ ءَايَةً لِّلنَّاسِ ۖ وَٱنظُرْ إِلَى ٱلْعِظَامِ كَيْفَ نُنشِزُهَا ثُمَّ نَكْسُوهَا لَحْمًا ۚ فَلَمَّا تَبَيَّنَ لَهُۥ قَالَ أَعْلَمُ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Or [consider such an example] as the one who passed by a township which had fallen into ruin. He said, \"How will Allāh bring this to life after its death?\" So Allāh caused him to die for a hundred years; then He revived him. He said, \"How long have you remained?\" He [the man] said, \"I have remained a day or part of a day.\" He said, \"Rather, you have remained one hundred years. Look at your food and your drink; it has not changed with time. And look at your donkey; and We will make you a sign for the people. And look at the bones [of this donkey] - how We raise them and then We cover them with flesh.\" And when it became clear to him, he said, \"I know that Allāh is over all things competent.\"","tr":"Aw kallathee marra AAalaqaryatin wahiya khawiyatun AAala AAurooshihaqala anna yuhyee hathihi AllahubaAAda mawtiha faamatahu Allahu mi-ata AAaminthumma baAAathahu qala kam labithta qala labithtuyawman aw baAAda yawmin qala bal labithta mi-ata AAaminfanthur ila taAAamikawasharabika lam yatasannah wanthurila himarika walinajAAalaka ayatan linnasiwanthur ila alAAithamikayfa nunshizuha thumma naksooha lahmanfalamma tabayyana lahu qala aAAlamu anna AllahaAAala kulli shay-in qadeer","juz":3,"page":43},{"s":2,"a":260,"key":"2:260","ar":"وَإِذْ قَالَ إِبْرَٰهِـۧمُ رَبِّ أَرِنِى كَيْفَ تُحْىِ ٱلْمَوْتَىٰ ۖ قَالَ أَوَلَمْ تُؤْمِن ۖ قَالَ بَلَىٰ وَلَـٰكِن لِّيَطْمَئِنَّ قَلْبِى ۖ قَالَ فَخُذْ أَرْبَعَةً مِّنَ ٱلطَّيْرِ فَصُرْهُنَّ إِلَيْكَ ثُمَّ ٱجْعَلْ عَلَىٰ كُلِّ جَبَلٍ مِّنْهُنَّ جُزْءًا ثُمَّ ٱدْعُهُنَّ يَأْتِينَكَ سَعْيًا ۚ وَٱعْلَمْ أَنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ","en":"And [mention] when Abraham said, \"My Lord, show me how You give life to the dead.\" [Allāh] said, \"Have you not believed?\" He said, \"Yes, but [I ask] only that my heart may be satisfied.\" [Allāh] said, \"Take four birds and commit them to yourself.1 Then [after slaughtering them] put on each hill a portion of them; then call them - they will come [flying] to you in haste. And know that Allāh is Exalted in Might and Wise.\"","tr":"Wa-ith qala ibraheemurabbi arinee kayfa tuhyee almawta qala awalam tu/min qala bala walakin liyatma-innaqalbee qala fakhuth arbaAAatan mina attayrifasurhunna ilayka thumma ijAAal AAala kulli jabalinminhunna juz-an thumma odAAuhunna ya/teenaka saAAyan waAAlamanna Allaha AAazeezun hakeem","juz":3,"page":44},{"s":2,"a":261,"key":"2:261","ar":"مَّثَلُ ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمْ فِى سَبِيلِ ٱللَّهِ كَمَثَلِ حَبَّةٍ أَنۢبَتَتْ سَبْعَ سَنَابِلَ فِى كُلِّ سُنۢبُلَةٍ مِّا۟ئَةُ حَبَّةٍ ۗ وَٱللَّهُ يُضَـٰعِفُ لِمَن يَشَآءُ ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ","en":"The example of those who spend their wealth in the way of Allāh is like a seed [of grain] which grows seven spikes; in each spike is a hundred grains. And Allāh multiplies [His reward] for whom He wills. And Allāh is all-Encompassing and Knowing.","tr":"Mathalu allatheena yunfiqoona amwalahumfee sabeeli Allahi kamathali habbatin anbatatsabAAa sanabila fee kulli sunbulatin mi-atu habbatinwallahu yudaAAifu liman yashao wallahuwasiAAun AAaleem","juz":3,"page":44},{"s":2,"a":262,"key":"2:262","ar":"ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمْ فِى سَبِيلِ ٱللَّهِ ثُمَّ لَا يُتْبِعُونَ مَآ أَنفَقُوا۟ مَنًّا وَلَآ أَذًى ۙ لَّهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"Those who spend their wealth in the way of Allāh and then do not follow up what they have spent with reminders [of it] or [other] injury will have their reward with their Lord, and there will be no fear concerning them, nor will they grieve.","tr":"Allatheena yunfiqoona amwalahumfee sabeeli Allahi thumma la yutbiAAoona maanfaqoo mannan wala athan lahum ajruhum AAindarabbihim wala khawfun AAalayhim wala hum yahzanoon","juz":3,"page":44},{"s":2,"a":263,"key":"2:263","ar":"۞ قَوْلٌ مَّعْرُوفٌ وَمَغْفِرَةٌ خَيْرٌ مِّن صَدَقَةٍ يَتْبَعُهَآ أَذًى ۗ وَٱللَّهُ غَنِىٌّ حَلِيمٌ","en":"Kind speech and forgiveness are better than charity followed by injury. And Allāh is Free of need and Forbearing.","tr":"Qawlun maAAroofun wamaghfiratun khayrun minsadaqatin yatbaAAuha athan wallahughaniyyun haleem","juz":3,"page":44},{"s":2,"a":264,"key":"2:264","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تُبْطِلُوا۟ صَدَقَـٰتِكُم بِٱلْمَنِّ وَٱلْأَذَىٰ كَٱلَّذِى يُنفِقُ مَالَهُۥ رِئَآءَ ٱلنَّاسِ وَلَا يُؤْمِنُ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ ۖ فَمَثَلُهُۥ كَمَثَلِ صَفْوَانٍ عَلَيْهِ تُرَابٌ فَأَصَابَهُۥ وَابِلٌ فَتَرَكَهُۥ صَلْدًا ۖ لَّا يَقْدِرُونَ عَلَىٰ شَىْءٍ مِّمَّا كَسَبُوا۟ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلْكَـٰفِرِينَ","en":"O you who have believed, do not invalidate your charities with reminders [of it] or injury as does one who spends his wealth [only] to be seen by the people and does not believe in Allāh and the Last Day. His example is like that of a [large] smooth stone upon which is dust and is hit by a downpour that leaves it bare. They are unable [to keep] anything of what they have earned. And Allāh does not guide the disbelieving people.","tr":"Ya ayyuha allatheena amanoola tubtiloo sadaqatikum bilmanniwal-atha kallathee yunfiqu malahuri-aa annasi wala yu/minu billahiwalyawmi al-akhiri famathaluhu kamathali safwaninAAalayhi turabun faasabahu wabilunfatarakahu saldan la yaqdiroona AAalashay-in mimma kasaboo wallahu layahdee alqawma alkafireen","juz":3,"page":44},{"s":2,"a":265,"key":"2:265","ar":"وَمَثَلُ ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمُ ٱبْتِغَآءَ مَرْضَاتِ ٱللَّهِ وَتَثْبِيتًا مِّنْ أَنفُسِهِمْ كَمَثَلِ جَنَّةٍۭ بِرَبْوَةٍ أَصَابَهَا وَابِلٌ فَـَٔاتَتْ أُكُلَهَا ضِعْفَيْنِ فَإِن لَّمْ يُصِبْهَا وَابِلٌ فَطَلٌّ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"And the example of those who spend their wealth seeking means to the approval of Allāh and assuring [reward for] themselves is like a garden on high ground which is hit by a downpour - so it yields its fruits in double. And [even] if it is not hit by a downpour, then a drizzle [is sufficient]. And Allāh, of what you do, is Seeing.","tr":"Wamathalu allatheena yunfiqoona amwalahumuibtighaa mardati Allahi watathbeetan minanfusihim kamathali jannatin birabwatin asabaha wabilunfaatat okulaha diAAfayni fa-in lam yusibhawabilun fatallun wallahu bimataAAmaloona baseer","juz":3,"page":45},{"s":2,"a":266,"key":"2:266","ar":"أَيَوَدُّ أَحَدُكُمْ أَن تَكُونَ لَهُۥ جَنَّةٌ مِّن نَّخِيلٍ وَأَعْنَابٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ لَهُۥ فِيهَا مِن كُلِّ ٱلثَّمَرَٰتِ وَأَصَابَهُ ٱلْكِبَرُ وَلَهُۥ ذُرِّيَّةٌ ضُعَفَآءُ فَأَصَابَهَآ إِعْصَارٌ فِيهِ نَارٌ فَٱحْتَرَقَتْ ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْـَٔايَـٰتِ لَعَلَّكُمْ تَتَفَكَّرُونَ","en":"Would one of you like to have a garden of palm trees and grapevines underneath which rivers flow in which he has from every fruit? But he is afflicted with old age and has weak [i.e., immature] offspring, and it is hit by a whirlwind containing fire and is burned. Thus does Allāh make clear to you [His] verses that you might give thought.","tr":"Ayawaddu ahadukum an takoona lahujannatun min nakheelin waaAAnabin tajree min tahtihaal-anharu lahu feeha min kulli aththamaratiwaasabahu alkibaru walahu thurriyyatun duAAafaofaasabaha iAAsarun feehi narun fahtaraqatkathalika yubayyinu Allahu lakumu al-ayatilaAAallakum tatafakkaroon","juz":3,"page":45},{"s":2,"a":267,"key":"2:267","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَنفِقُوا۟ مِن طَيِّبَـٰتِ مَا كَسَبْتُمْ وَمِمَّآ أَخْرَجْنَا لَكُم مِّنَ ٱلْأَرْضِ ۖ وَلَا تَيَمَّمُوا۟ ٱلْخَبِيثَ مِنْهُ تُنفِقُونَ وَلَسْتُم بِـَٔاخِذِيهِ إِلَّآ أَن تُغْمِضُوا۟ فِيهِ ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ غَنِىٌّ حَمِيدٌ","en":"O you who have believed, spend from the good things which you have earned and from that which We have produced for you from the earth. And do not aim toward the defective therefrom, spending [from that] while you would not take it [yourself] except with closed eyes. And know that Allāh is Free of need and Praiseworthy.","tr":"Ya ayyuha allatheena amanooanfiqoo min tayyibati ma kasabtum wamimmaakhrajna lakum mina al-ardi wala tayammamooalkhabeetha minhu tunfiqoona walastum bi-akhitheehiilla an tughmidoo feehi waAAlamoo anna Allahaghaniyyun hameed","juz":3,"page":45},{"s":2,"a":268,"key":"2:268","ar":"ٱلشَّيْطَـٰنُ يَعِدُكُمُ ٱلْفَقْرَ وَيَأْمُرُكُم بِٱلْفَحْشَآءِ ۖ وَٱللَّهُ يَعِدُكُم مَّغْفِرَةً مِّنْهُ وَفَضْلًا ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ","en":"Satan threatens you with poverty and orders you to immorality, while Allāh promises you forgiveness from Him and bounty. And Allāh is all-Encompassing and Knowing.","tr":"Ashshaytanu yaAAidukumualfaqra waya/murukum bilfahsha-i wallahuyaAAidukum maghfiratan minhu wafadlan wallahuwasiAAun AAaleem","juz":3,"page":45},{"s":2,"a":269,"key":"2:269","ar":"يُؤْتِى ٱلْحِكْمَةَ مَن يَشَآءُ ۚ وَمَن يُؤْتَ ٱلْحِكْمَةَ فَقَدْ أُوتِىَ خَيْرًا كَثِيرًا ۗ وَمَا يَذَّكَّرُ إِلَّآ أُو۟لُوا۟ ٱلْأَلْبَـٰبِ","en":"He gives wisdom1 to whom He wills, and whoever has been given wisdom has certainly been given much good. And none will remember except those of understanding.","tr":"Yu/tee alhikmata man yashaowaman yu/ta alhikmata faqad ootiya khayran katheeran wamayaththakkaru illa oloo al-albab","juz":3,"page":45},{"s":2,"a":270,"key":"2:270","ar":"وَمَآ أَنفَقْتُم مِّن نَّفَقَةٍ أَوْ نَذَرْتُم مِّن نَّذْرٍ فَإِنَّ ٱللَّهَ يَعْلَمُهُۥ ۗ وَمَا لِلظَّـٰلِمِينَ مِنْ أَنصَارٍ","en":"And whatever you spend of expenditures or make of vows - indeed, Allāh knows of it. And for the wrongdoers there are no helpers.","tr":"Wama anfaqtum min nafaqatin aw nathartummin nathrin fa-inna Allaha yaAAlamuhu wamaliththalimeena min ansar","juz":3,"page":46},{"s":2,"a":271,"key":"2:271","ar":"إِن تُبْدُوا۟ ٱلصَّدَقَـٰتِ فَنِعِمَّا هِىَ ۖ وَإِن تُخْفُوهَا وَتُؤْتُوهَا ٱلْفُقَرَآءَ فَهُوَ خَيْرٌ لَّكُمْ ۚ وَيُكَفِّرُ عَنكُم مِّن سَيِّـَٔاتِكُمْ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌ","en":"If you disclose your charitable expenditures, they are good; but if you conceal them and give them to the poor, it is better for you, and He will remove from you some of your misdeeds [thereby]. And Allāh, of what you do, is [fully] Aware.","tr":"In tubdoo assadaqatifaniAAimma hiya wa-in tukhfooha watu/toohaalfuqaraa fahuwa khayrun lakum wayukaffiru AAankum minsayyi-atikum wallahu bimataAAmaloona khabeer","juz":3,"page":46},{"s":2,"a":272,"key":"2:272","ar":"۞ لَّيْسَ عَلَيْكَ هُدَىٰهُمْ وَلَـٰكِنَّ ٱللَّهَ يَهْدِى مَن يَشَآءُ ۗ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍ فَلِأَنفُسِكُمْ ۚ وَمَا تُنفِقُونَ إِلَّا ٱبْتِغَآءَ وَجْهِ ٱللَّهِ ۚ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍ يُوَفَّ إِلَيْكُمْ وَأَنتُمْ لَا تُظْلَمُونَ","en":"Not upon you, [O Muḥammad], is [responsibility for] their guidance, but Allāh guides whom He wills. And whatever good you [believers] spend is for yourselves, and you do not spend except seeking the face [i.e., approval] of Allāh. And whatever you spend of good1 - it will be fully repaid to you, and you will not be wronged.","tr":"Laysa AAalayka hudahum walakinnaAllaha yahdee man yashao wama tunfiqoo minkhayrin fali-anfusikum wama tunfiqoona illa ibtighaawajhi Allahi wama tunfiqoo min khayrin yuwaffailaykum waantum la tuthlamoon","juz":3,"page":46},{"s":2,"a":273,"key":"2:273","ar":"لِلْفُقَرَآءِ ٱلَّذِينَ أُحْصِرُوا۟ فِى سَبِيلِ ٱللَّهِ لَا يَسْتَطِيعُونَ ضَرْبًا فِى ٱلْأَرْضِ يَحْسَبُهُمُ ٱلْجَاهِلُ أَغْنِيَآءَ مِنَ ٱلتَّعَفُّفِ تَعْرِفُهُم بِسِيمَـٰهُمْ لَا يَسْـَٔلُونَ ٱلنَّاسَ إِلْحَافًا ۗ وَمَا تُنفِقُوا۟ مِنْ خَيْرٍ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌ","en":"[Charity is] for the poor who have been restricted for the cause of Allāh, unable to move about in the land. An ignorant [person] would think them self-sufficient because of their restraint, but you will know them by their [characteristic] sign. They do not ask people persistently [or at all]. And whatever you spend of good - indeed, Allāh is Knowing of it.","tr":"Lilfuqara-i allatheena ohsiroofee sabeeli Allahi la yastateeAAoona darbanfee al-ardi yahsabuhumu aljahilu aghniyaamina attaAAaffufi taAArifuhum biseemahum layas-aloona annasa ilhafan wamatunfiqoo min khayrin fa-inna Allaha bihi AAaleem","juz":3,"page":46},{"s":2,"a":274,"key":"2:274","ar":"ٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُم بِٱلَّيْلِ وَٱلنَّهَارِ سِرًّا وَعَلَانِيَةً فَلَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"Those who spend their wealth [in Allāh's way] by night and by day, secretly and publicly - they will have their reward with their Lord. And no fear will there be concerning them, nor will they grieve.","tr":"Allatheena yunfiqoona amwalahumbillayli wannahari sirran waAAalaniyatanfalahum ajruhum AAinda rabbihim wala khawfun AAalayhim walahum yahzanoon","juz":3,"page":46},{"s":2,"a":275,"key":"2:275","ar":"ٱلَّذِينَ يَأْكُلُونَ ٱلرِّبَوٰا۟ لَا يَقُومُونَ إِلَّا كَمَا يَقُومُ ٱلَّذِى يَتَخَبَّطُهُ ٱلشَّيْطَـٰنُ مِنَ ٱلْمَسِّ ۚ ذَٰلِكَ بِأَنَّهُمْ قَالُوٓا۟ إِنَّمَا ٱلْبَيْعُ مِثْلُ ٱلرِّبَوٰا۟ ۗ وَأَحَلَّ ٱللَّهُ ٱلْبَيْعَ وَحَرَّمَ ٱلرِّبَوٰا۟ ۚ فَمَن جَآءَهُۥ مَوْعِظَةٌ مِّن رَّبِّهِۦ فَٱنتَهَىٰ فَلَهُۥ مَا سَلَفَ وَأَمْرُهُۥٓ إِلَى ٱللَّهِ ۖ وَمَنْ عَادَ فَأُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"Those who consume interest1 cannot stand [on the Day of Resurrection] except as one stands who is being beaten by Satan into insanity. That is because they say, \"Trade is [just] like interest.\" But Allāh has permitted trade and has forbidden interest. So whoever has received an admonition from his Lord and desists may have what is past, and his affair rests with Allāh. But whoever returns [to dealing in interest or usury] - those are the companions of the Fire; they will abide eternally therein.","tr":"Allatheena ya/kuloona arribala yaqoomoona illa kama yaqoomu allatheeyatakhabbatuhu ashshaytanu mina almassi thalikabi-annahum qaloo innama albayAAu mithlu arribawaahalla Allahu albayAAa waharrama arribafaman jaahu mawAAithatun min rabbihi fantahafalahu ma salafa waamruhu ila Allahi wamanAAada faola-ika as-habu annarihum feeha khalidoon","juz":3,"page":47},{"s":2,"a":276,"key":"2:276","ar":"يَمْحَقُ ٱللَّهُ ٱلرِّبَوٰا۟ وَيُرْبِى ٱلصَّدَقَـٰتِ ۗ وَٱللَّهُ لَا يُحِبُّ كُلَّ كَفَّارٍ أَثِيمٍ","en":"Allāh destroys interest and gives increase for charities. And Allāh does not like every sinning disbeliever.","tr":"Yamhaqu Allahu arribawayurbee assadaqati wallahula yuhibbu kulla kaffarin atheem","juz":3,"page":47},{"s":2,"a":277,"key":"2:277","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَءَاتَوُا۟ ٱلزَّكَوٰةَ لَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ وَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"Indeed, those who believe and do righteous deeds and establish prayer and give zakāh will have their reward with their Lord, and there will be no fear concerning them, nor will they grieve.","tr":"Inna allatheena amanoowaAAamiloo assalihati waaqamoo assalatawaatawoo azzakata lahum ajruhum AAindarabbihim wala khawfun AAalayhim wala hum yahzanoon","juz":3,"page":47},{"s":2,"a":278,"key":"2:278","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَذَرُوا۟ مَا بَقِىَ مِنَ ٱلرِّبَوٰٓا۟ إِن كُنتُم مُّؤْمِنِينَ","en":"O you who have believed, fear Allāh and give up what remains [due to you] of interest, if you should be believers.","tr":"Ya ayyuha allatheena amanooittaqoo Allaha watharoo ma baqiya mina arribain kuntum mu/mineen","juz":3,"page":47},{"s":2,"a":279,"key":"2:279","ar":"فَإِن لَّمْ تَفْعَلُوا۟ فَأْذَنُوا۟ بِحَرْبٍ مِّنَ ٱللَّهِ وَرَسُولِهِۦ ۖ وَإِن تُبْتُمْ فَلَكُمْ رُءُوسُ أَمْوَٰلِكُمْ لَا تَظْلِمُونَ وَلَا تُظْلَمُونَ","en":"And if you do not, then be informed of a war [against you] from Allāh and His Messenger. But if you repent, you may have your principal - [thus] you do no wrong, nor are you wronged.","tr":"Fa-in lam tafAAaloo fa/thanoo biharbinmina Allahi warasoolihi wa-in tubtum falakum ruoosu amwalikumla tathlimoona wala tuthlamoon","juz":3,"page":47},{"s":2,"a":280,"key":"2:280","ar":"وَإِن كَانَ ذُو عُسْرَةٍ فَنَظِرَةٌ إِلَىٰ مَيْسَرَةٍ ۚ وَأَن تَصَدَّقُوا۟ خَيْرٌ لَّكُمْ ۖ إِن كُنتُمْ تَعْلَمُونَ","en":"And if someone is in hardship, then [let there be] postponement until [a time of] ease. But if you give [from your right as] charity, then it is better for you, if you only knew.","tr":"Wa-in kana thoo AAusratinfanathiratun ila maysaratin waan tasaddaqookhayrun lakum in kuntum taAAlamoon","juz":3,"page":47},{"s":2,"a":281,"key":"2:281","ar":"وَٱتَّقُوا۟ يَوْمًا تُرْجَعُونَ فِيهِ إِلَى ٱللَّهِ ۖ ثُمَّ تُوَفَّىٰ كُلُّ نَفْسٍ مَّا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ","en":"And fear a Day when you will be returned to Allāh. Then every soul will be compensated for what it earned, and they will not be wronged [i.e., treated unjustly].","tr":"Wattaqoo yawman turjaAAoona feehiila Allahi thumma tuwaffa kullu nafsin makasabat wahum la yuthlamoon","juz":3,"page":47},{"s":2,"a":282,"key":"2:282","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا تَدَايَنتُم بِدَيْنٍ إِلَىٰٓ أَجَلٍ مُّسَمًّى فَٱكْتُبُوهُ ۚ وَلْيَكْتُب بَّيْنَكُمْ كَاتِبٌۢ بِٱلْعَدْلِ ۚ وَلَا يَأْبَ كَاتِبٌ أَن يَكْتُبَ كَمَا عَلَّمَهُ ٱللَّهُ ۚ فَلْيَكْتُبْ وَلْيُمْلِلِ ٱلَّذِى عَلَيْهِ ٱلْحَقُّ وَلْيَتَّقِ ٱللَّهَ رَبَّهُۥ وَلَا يَبْخَسْ مِنْهُ شَيْـًٔا ۚ فَإِن كَانَ ٱلَّذِى عَلَيْهِ ٱلْحَقُّ سَفِيهًا أَوْ ضَعِيفًا أَوْ لَا يَسْتَطِيعُ أَن يُمِلَّ هُوَ فَلْيُمْلِلْ وَلِيُّهُۥ بِٱلْعَدْلِ ۚ وَٱسْتَشْهِدُوا۟ شَهِيدَيْنِ مِن رِّجَالِكُمْ ۖ فَإِن لَّمْ يَكُونَا رَجُلَيْنِ فَرَجُلٌ وَٱمْرَأَتَانِ مِمَّن تَرْضَوْنَ مِنَ ٱلشُّهَدَآءِ أَن تَضِلَّ إِحْدَىٰهُمَا فَتُذَكِّرَ إِحْدَىٰهُمَا ٱلْأُخْرَىٰ ۚ وَلَا يَأْبَ ٱلشُّهَدَآءُ إِذَا مَا دُعُوا۟ ۚ وَلَا تَسْـَٔمُوٓا۟ أَن تَكْتُبُوهُ صَغِيرًا أَوْ كَبِيرًا إِلَىٰٓ أَجَلِهِۦ ۚ ذَٰلِكُمْ أَقْسَطُ عِندَ ٱللَّهِ وَأَقْوَمُ لِلشَّهَـٰدَةِ وَأَدْنَىٰٓ أَلَّا تَرْتَابُوٓا۟ ۖ إِلَّآ أَن تَكُونَ تِجَـٰرَةً حَاضِرَةً تُدِيرُونَهَا بَيْنَكُمْ فَلَيْسَ عَلَيْكُمْ جُنَاحٌ أَلَّا تَكْتُبُوهَا ۗ وَأَشْهِدُوٓا۟ إِذَا تَبَايَعْتُمْ ۚ وَلَا يُضَآرَّ كَاتِبٌ وَلَا شَهِيدٌ ۚ وَإِن تَفْعَلُوا۟ فَإِنَّهُۥ فُسُوقٌۢ بِكُمْ ۗ وَٱتَّقُوا۟ ٱللَّهَ ۖ وَيُعَلِّمُكُمُ ٱللَّهُ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"O you who have believed, when you contract a debt for a specified term, write it down. And let a scribe write [it] between you in justice. Let no scribe refuse to write as Allāh has taught him. So let him write and let the one who has the obligation [i.e., the debtor] dictate. And let him fear Allāh, his Lord, and not leave anything out of it. But if the one who has the obligation is of limited understanding or weak or unable to dictate himself, then let his guardian dictate in justice. And bring to witness two witnesses from among your men. And if there are not two men [available], then a man and two women from those whom you accept as witnesses - so that if one of them [i.e., the women] errs, then the other can remind her. And let not the witnesses refuse when they are called upon. And do not be [too] weary to write it, whether it is small or large, for its [specified] term. That is more just in the sight of Allāh and stronger as evidence and more likely to prevent doubt between you, except when it is an immediate transaction which you conduct among yourselves. For [then] there is no blame upon you if you do not write it. And take witnesses when you conclude a contract. Let no scribe be harmed or any witness. For if you do so, indeed, it is [grave] disobedience in you. And fear Allāh. And Allāh teaches you. And Allāh is Knowing of all things.","tr":"Ya ayyuha allatheena amanooitha tadayantum bidaynin ila ajalin musammanfaktuboohu walyaktub baynakum katibun bilAAadliwala ya/ba katibun an yaktuba kamaAAallamahu Allahu falyaktub walyumlili allatheeAAalayhi alhaqqu walyattaqi Allaha rabbahu walayabkhas minhu shay-an fa-in kana allathee AAalayhialhaqqu safeehan aw daAAeefan aw la yastateeAAuan yumilla huwa falyumlil waliyyuhu bilAAadli wastashhidooshaheedayni min rijalikum fa-in lam yakoonarajulayni farajulun wamraatani mimman tardawnamina ashshuhada-i an tadilla ihdahumafatuthakkira ihdahuma al-okhrawala ya/ba ashshuhadao itha maduAAoo wala tas-amoo an taktuboohu sagheeran awkabeeran ila ajalihi thalikum aqsatu AAindaAllahi waaqwamu lishshahadati waadnaalla tartaboo illa an takoona tijaratanhadiratan tudeeroonaha baynakum falaysa AAalaykumjunahun alla taktubooha waashhidoo ithatabayaAAtum wala yudarra katibun walashaheedun wa-in tafAAaloo fa-innahu fusooqun bikum wattaqooAllaha wayuAAallimukumu Allahu wallahubikulli shay-in AAaleem","juz":3,"page":48},{"s":2,"a":283,"key":"2:283","ar":"۞ وَإِن كُنتُمْ عَلَىٰ سَفَرٍ وَلَمْ تَجِدُوا۟ كَاتِبًا فَرِهَـٰنٌ مَّقْبُوضَةٌ ۖ فَإِنْ أَمِنَ بَعْضُكُم بَعْضًا فَلْيُؤَدِّ ٱلَّذِى ٱؤْتُمِنَ أَمَـٰنَتَهُۥ وَلْيَتَّقِ ٱللَّهَ رَبَّهُۥ ۗ وَلَا تَكْتُمُوا۟ ٱلشَّهَـٰدَةَ ۚ وَمَن يَكْتُمْهَا فَإِنَّهُۥٓ ءَاثِمٌ قَلْبُهُۥ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ عَلِيمٌ","en":"And if you are on a journey and cannot find a scribe, then a security deposit [should be] taken. And if one of you entrusts another, then let him who is entrusted discharge his trust [faithfully] and let him fear Allāh, his Lord. And do not conceal testimony, for whoever conceals it - his heart is indeed sinful, and Allāh is Knowing of what you do.","tr":"Wa-in kuntum AAala safarin walamtajidoo katiban farihanun maqboodatun fa-inamina baAAdukum baAAdan falyu-addiallatheei/tumina amanatahu walyattaqi Allaha rabbahuwala taktumoo ashshahadata waman yaktumhafa-innahu athimun qalbuhu wallahu bimataAAmaloona AAaleem","juz":3,"page":49},{"s":2,"a":284,"key":"2:284","ar":"لِّلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَإِن تُبْدُوا۟ مَا فِىٓ أَنفُسِكُمْ أَوْ تُخْفُوهُ يُحَاسِبْكُم بِهِ ٱللَّهُ ۖ فَيَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"To Allāh belongs whatever is in the heavens and whatever is in the earth. Whether you show what is within yourselves or conceal it, Allāh will bring you to account for it. Then He will forgive whom He wills and punish whom He wills, and Allāh is over all things competent.","tr":"Lillahi ma fee assamawatiwama fee al-ardi wa-in tubdoo ma feeanfusikum aw tukhfoohu yuhasibkum bihi Allahufayaghfiru liman yashao wayuAAaththibu man yashaowallahu AAala kulli shay-in qadeer","juz":3,"page":49},{"s":2,"a":285,"key":"2:285","ar":"ءَامَنَ ٱلرَّسُولُ بِمَآ أُنزِلَ إِلَيْهِ مِن رَّبِّهِۦ وَٱلْمُؤْمِنُونَ ۚ كُلٌّ ءَامَنَ بِٱللَّهِ وَمَلَـٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِّن رُّسُلِهِۦ ۚ وَقَالُوا۟ سَمِعْنَا وَأَطَعْنَا ۖ غُفْرَانَكَ رَبَّنَا وَإِلَيْكَ ٱلْمَصِيرُ","en":"The Messenger has believed in what was revealed to him from his Lord, and [so have] the believers. All of them have believed in Allāh and His angels and His books and His messengers, [saying], \"We make no distinction between any of His messengers.\" And they say, \"We hear and we obey. [We seek] Your forgiveness, our Lord, and to You is the [final] destination.\"","tr":"Amana arrasoolu bimaonzila ilayhi min rabbihi walmu/minoona kullun amanabillahi wamala-ikatihi wakutubihiwarusulihi la nufarriqu bayna ahadin min rusulihiwaqaloo samiAAna waataAAna ghufranakarabbana wa-ilayka almaseer","juz":3,"page":49},{"s":2,"a":286,"key":"2:286","ar":"لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا وُسْعَهَا ۚ لَهَا مَا كَسَبَتْ وَعَلَيْهَا مَا ٱكْتَسَبَتْ ۗ رَبَّنَا لَا تُؤَاخِذْنَآ إِن نَّسِينَآ أَوْ أَخْطَأْنَا ۚ رَبَّنَا وَلَا تَحْمِلْ عَلَيْنَآ إِصْرًا كَمَا حَمَلْتَهُۥ عَلَى ٱلَّذِينَ مِن قَبْلِنَا ۚ رَبَّنَا وَلَا تُحَمِّلْنَا مَا لَا طَاقَةَ لَنَا بِهِۦ ۖ وَٱعْفُ عَنَّا وَٱغْفِرْ لَنَا وَٱرْحَمْنَآ ۚ أَنتَ مَوْلَىٰنَا فَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَـٰفِرِينَ","en":"Allāh does not charge a soul except [with that within] its capacity. It will have [the consequence of] what [good] it has gained, and it will bear [the consequence of] what [evil] it has earned. \"Our Lord, do not impose blame upon us if we have forgotten or erred. Our Lord, and lay not upon us a burden like that which You laid upon those before us. Our Lord, and burden us not with that which we have no ability to bear. And pardon us; and forgive us; and have mercy upon us. You are our protector, so give us victory over the disbelieving people.\"1","tr":"La yukallifu Allahu nafsanilla wusAAaha laha ma kasabatwaAAalayha ma iktasabat rabbana latu-akhithna in naseena aw akhta/narabbana wala tahmil AAalayna isrankama hamaltahu AAala allatheena minqablina rabbana wala tuhammilnama la taqata lana bihi waAAfuAAanna waghfir lana warhamnaanta mawlana fansurna AAalaalqawmi alkafireen","juz":3,"page":49},{"s":3,"a":1,"key":"3:1","ar":" الٓمٓ","en":"Alif, Lām, Meem.1","tr":"Alif-lam-meem","juz":3,"page":50},{"s":3,"a":2,"key":"3:2","ar":"ٱللَّهُ لَآ إِلَـٰهَ إِلَّا هُوَ ٱلْحَىُّ ٱلْقَيُّومُ","en":"Allāh - there is no deity except Him, the Ever-Living, the Self-Sustaining.1","tr":"Allahu la ilaha illahuwa alhayyu alqayyoom","juz":3,"page":50},{"s":3,"a":3,"key":"3:3","ar":"نَزَّلَ عَلَيْكَ ٱلْكِتَـٰبَ بِٱلْحَقِّ مُصَدِّقًا لِّمَا بَيْنَ يَدَيْهِ وَأَنزَلَ ٱلتَّوْرَىٰةَ وَٱلْإِنجِيلَ","en":"He has sent down upon you, [O Muḥammad], the Book in truth, confirming what was before it. And He revealed the Torah and the Gospel","tr":"Nazzala AAalayka alkitaba bilhaqqimusaddiqan lima bayna yadayhi waanzala attawratawal-injeel","juz":3,"page":50},{"s":3,"a":4,"key":"3:4","ar":"مِن قَبْلُ هُدًى لِّلنَّاسِ وَأَنزَلَ ٱلْفُرْقَانَ ۗ إِنَّ ٱلَّذِينَ كَفَرُوا۟ بِـَٔايَـٰتِ ٱللَّهِ لَهُمْ عَذَابٌ شَدِيدٌ ۗ وَٱللَّهُ عَزِيزٌ ذُو ٱنتِقَامٍ","en":"Before, as guidance for the people. And He revealed the Criterion [i.e., the Qur’ān]. Indeed, those who disbelieve in the verses of Allāh will have a severe punishment, and Allāh is Exalted in Might, the Owner of Retribution.1","tr":"Min qablu hudan linnasiwaanzala alfurqana inna allatheena kafaroo bi-ayatiAllahi lahum AAathabun shadeedun wallahuAAazeezun thoo intiqam","juz":3,"page":50},{"s":3,"a":5,"key":"3:5","ar":"إِنَّ ٱللَّهَ لَا يَخْفَىٰ عَلَيْهِ شَىْءٌ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ","en":"Indeed, from Allāh nothing is hidden in the earth nor in the heaven.","tr":"Inna Allaha la yakhfaAAalayhi shay-on fee al-ardi wala fee assama/-","juz":3,"page":50},{"s":3,"a":6,"key":"3:6","ar":"هُوَ ٱلَّذِى يُصَوِّرُكُمْ فِى ٱلْأَرْحَامِ كَيْفَ يَشَآءُ ۚ لَآ إِلَـٰهَ إِلَّا هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"It is He who forms you in the wombs however He wills. There is no deity except Him, the Exalted in Might, the Wise.","tr":"Huwa allathee yusawwirukum feeal-arhami kayfa yashao la ilaha illahuwa alAAazeezu alhakeem","juz":3,"page":50},{"s":3,"a":7,"key":"3:7","ar":"هُوَ ٱلَّذِىٓ أَنزَلَ عَلَيْكَ ٱلْكِتَـٰبَ مِنْهُ ءَايَـٰتٌ مُّحْكَمَـٰتٌ هُنَّ أُمُّ ٱلْكِتَـٰبِ وَأُخَرُ مُتَشَـٰبِهَـٰتٌ ۖ فَأَمَّا ٱلَّذِينَ فِى قُلُوبِهِمْ زَيْغٌ فَيَتَّبِعُونَ مَا تَشَـٰبَهَ مِنْهُ ٱبْتِغَآءَ ٱلْفِتْنَةِ وَٱبْتِغَآءَ تَأْوِيلِهِۦ ۗ وَمَا يَعْلَمُ تَأْوِيلَهُۥٓ إِلَّا ٱللَّهُ ۗ وَٱلرَّٰسِخُونَ فِى ٱلْعِلْمِ يَقُولُونَ ءَامَنَّا بِهِۦ كُلٌّ مِّنْ عِندِ رَبِّنَا ۗ وَمَا يَذَّكَّرُ إِلَّآ أُو۟لُوا۟ ٱلْأَلْبَـٰبِ","en":"It is He who has sent down to you, [O Muḥammad], the Book; in it are verses [that are] precise - they are the foundation of the Book - and others unspecific.1 As for those in whose hearts is deviation [from truth], they will follow that of it which is unspecific, seeking discord and seeking an interpretation [suitable to them]. And no one knows its [true] interpretation except Allāh. But those firm in knowledge say, \"We believe in it. All [of it] is from our Lord.\" And no one will be reminded except those of understanding.","tr":"Huwa allathee anzala AAalayka alkitabaminhu ayatun muhkamatun hunna ommualkitabi waokharu mutashabihatun faammaallatheena fee quloobihim zayghun fayattabiAAoona matashabaha minhu ibtighaa alfitnati wabtighaata/weelihi wama yaAAlamu ta/weelahu illa Allahuwarrasikhoona fee alAAilmi yaqooloona amannabihi kullun min AAindi rabbina wama yaththakkaruilla oloo al-albab","juz":3,"page":50},{"s":3,"a":8,"key":"3:8","ar":"رَبَّنَا لَا تُزِغْ قُلُوبَنَا بَعْدَ إِذْ هَدَيْتَنَا وَهَبْ لَنَا مِن لَّدُنكَ رَحْمَةً ۚ إِنَّكَ أَنتَ ٱلْوَهَّابُ","en":"[Who say], \"Our Lord, let not our hearts deviate after You have guided us and grant us from Yourself mercy. Indeed, You are the Bestower.1","tr":"Rabbana la tuzigh quloobanabaAAda ith hadaytana wahab lana min ladunkarahmatan innaka anta alwahhab","juz":3,"page":50},{"s":3,"a":9,"key":"3:9","ar":"رَبَّنَآ إِنَّكَ جَامِعُ ٱلنَّاسِ لِيَوْمٍ لَّا رَيْبَ فِيهِ ۚ إِنَّ ٱللَّهَ لَا يُخْلِفُ ٱلْمِيعَادَ","en":"Our Lord, surely You will gather the people for a Day about which there is no doubt. Indeed, Allāh does not fail in His promise.\"","tr":"Rabbana innaka jamiAAu annasiliyawmin la rayba feehi inna Allaha layukhlifu almeeAAad","juz":3,"page":50},{"s":3,"a":10,"key":"3:10","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ لَن تُغْنِىَ عَنْهُمْ أَمْوَٰلُهُمْ وَلَآ أَوْلَـٰدُهُم مِّنَ ٱللَّهِ شَيْـًٔا ۖ وَأُو۟لَـٰٓئِكَ هُمْ وَقُودُ ٱلنَّارِ","en":"Indeed, those who disbelieve - never will their wealth or their children avail them against Allāh at all. And it is they who are fuel for the Fire.","tr":"Inna allatheena kafaroo lan tughniyaAAanhum amwaluhum wala awladuhum mina Allahishay-an waola-ika hum waqoodu annar","juz":3,"page":51},{"s":3,"a":11,"key":"3:11","ar":"كَدَأْبِ ءَالِ فِرْعَوْنَ وَٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَذَّبُوا۟ بِـَٔايَـٰتِنَا فَأَخَذَهُمُ ٱللَّهُ بِذُنُوبِهِمْ ۗ وَٱللَّهُ شَدِيدُ ٱلْعِقَابِ","en":"[Theirs is] like the custom of the people of Pharaoh and those before them. They denied Our signs, so Allāh seized them for their sins. And Allāh is severe in penalty.","tr":"Kada/bi ali firAAawna wallatheenamin qablihim kaththaboo bi-ayatinafaakhathahumu Allahu bithunoobihim wallahushadeedu alAAiqab","juz":3,"page":51},{"s":3,"a":12,"key":"3:12","ar":"قُل لِّلَّذِينَ كَفَرُوا۟ سَتُغْلَبُونَ وَتُحْشَرُونَ إِلَىٰ جَهَنَّمَ ۚ وَبِئْسَ ٱلْمِهَادُ","en":"Say to those who disbelieve, \"You will be overcome and gathered together to Hell, and wretched is the resting place.\"","tr":"Qul lillatheena kafaroo satughlaboonawatuhsharoona ila jahannama wabi/sa almihad","juz":3,"page":51},{"s":3,"a":13,"key":"3:13","ar":"قَدْ كَانَ لَكُمْ ءَايَةٌ فِى فِئَتَيْنِ ٱلْتَقَتَا ۖ فِئَةٌ تُقَـٰتِلُ فِى سَبِيلِ ٱللَّهِ وَأُخْرَىٰ كَافِرَةٌ يَرَوْنَهُم مِّثْلَيْهِمْ رَأْىَ ٱلْعَيْنِ ۚ وَٱللَّهُ يُؤَيِّدُ بِنَصْرِهِۦ مَن يَشَآءُ ۗ إِنَّ فِى ذَٰلِكَ لَعِبْرَةً لِّأُو۟لِى ٱلْأَبْصَـٰرِ","en":"Already there has been for you a sign in the two armies which met [in combat at Badr] - one fighting in the cause of Allāh and another of disbelievers. They saw them [to be] twice their [own] number by [their] eyesight.1 But Allāh supports with His victory whom He wills. Indeed in that is a lesson for those of vision.","tr":"Qad kana lakum ayatun feefi-atayni iltaqata fi-atun tuqatilu fee sabeeli Allahiwaokhra kafiratun yarawnahum mithlayhim ra/yaalAAayni wallahu yu-ayyidu binasrihi manyashao inna fee thalika laAAibratan li-olee al-absar","juz":3,"page":51},{"s":3,"a":14,"key":"3:14","ar":"زُيِّنَ لِلنَّاسِ حُبُّ ٱلشَّهَوَٰتِ مِنَ ٱلنِّسَآءِ وَٱلْبَنِينَ وَٱلْقَنَـٰطِيرِ ٱلْمُقَنطَرَةِ مِنَ ٱلذَّهَبِ وَٱلْفِضَّةِ وَٱلْخَيْلِ ٱلْمُسَوَّمَةِ وَٱلْأَنْعَـٰمِ وَٱلْحَرْثِ ۗ ذَٰلِكَ مَتَـٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَٱللَّهُ عِندَهُۥ حُسْنُ ٱلْمَـَٔابِ","en":"Beautified for people is the love of that which they desire - of women and sons, heaped-up sums of gold and silver, fine branded horses, and cattle and tilled land. That is the enjoyment of worldly life, but Allāh has with Him the best return [i.e., Paradise].","tr":"Zuyyina linnasi hubbuashshahawati mina annisa-i walbaneenawalqanateeri almuqantarati mina aththahabiwalfiddati walkhayli almusawwamati wal-anAAamiwalharthi thalika mataAAu alhayatiaddunya wallahu AAindahu husnualmaab","juz":3,"page":51},{"s":3,"a":15,"key":"3:15","ar":"۞ قُلْ أَؤُنَبِّئُكُم بِخَيْرٍ مِّن ذَٰلِكُمْ ۚ لِلَّذِينَ ٱتَّقَوْا۟ عِندَ رَبِّهِمْ جَنَّـٰتٌ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا وَأَزْوَٰجٌ مُّطَهَّرَةٌ وَرِضْوَٰنٌ مِّنَ ٱللَّهِ ۗ وَٱللَّهُ بَصِيرٌۢ بِٱلْعِبَادِ","en":"Say, \"Shall I inform you of [something] better than that? For those who fear Allāh will be gardens in the presence of their Lord beneath which rivers flow, wherein they abide eternally, and purified spouses and approval from Allāh. And Allāh is Seeing [i.e., aware] of [His] servants -","tr":"Qul aonabbi-okum bikhayrin min thalikumlillatheena ittaqaw AAinda rabbihim jannatun tajreemin tahtiha al-anharu khalideena feehawaazwajun mutahharatun waridwanunmina Allahi wallahu baseerun bilAAibad","juz":3,"page":51},{"s":3,"a":16,"key":"3:16","ar":"ٱلَّذِينَ يَقُولُونَ رَبَّنَآ إِنَّنَآ ءَامَنَّا فَٱغْفِرْ لَنَا ذُنُوبَنَا وَقِنَا عَذَابَ ٱلنَّارِ","en":"Those who say, \"Our Lord, indeed we have believed, so forgive us our sins and protect us from the punishment of the Fire,\"","tr":"Allatheena yaqooloona rabbanainnana amanna faghfir lana thunoobanawaqina AAathaba annar","juz":3,"page":52},{"s":3,"a":17,"key":"3:17","ar":"ٱلصَّـٰبِرِينَ وَٱلصَّـٰدِقِينَ وَٱلْقَـٰنِتِينَ وَٱلْمُنفِقِينَ وَٱلْمُسْتَغْفِرِينَ بِٱلْأَسْحَارِ","en":"The patient, the true, the obedient, those who spend [in the way of Allāh], and those who seek forgiveness before dawn.","tr":"Assabireena wassadiqeenawalqaniteena walmunfiqeena walmustaghfireenabil-ashar","juz":3,"page":52},{"s":3,"a":18,"key":"3:18","ar":"شَهِدَ ٱللَّهُ أَنَّهُۥ لَآ إِلَـٰهَ إِلَّا هُوَ وَٱلْمَلَـٰٓئِكَةُ وَأُو۟لُوا۟ ٱلْعِلْمِ قَآئِمًۢا بِٱلْقِسْطِ ۚ لَآ إِلَـٰهَ إِلَّا هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Allāh witnesses that there is no deity except Him, and [so do] the angels and those of knowledge - [that He is] maintaining [creation] in justice. There is no deity except Him, the Exalted in Might, the Wise.","tr":"Shahida Allahu annahu la ilahailla huwa walmala-ikatu waoloo alAAilmi qa-imanbilqisti la ilaha illa huwaalAAazeezu alhakeem","juz":3,"page":52},{"s":3,"a":19,"key":"3:19","ar":"إِنَّ ٱلدِّينَ عِندَ ٱللَّهِ ٱلْإِسْلَـٰمُ ۗ وَمَا ٱخْتَلَفَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ إِلَّا مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْعِلْمُ بَغْيًۢا بَيْنَهُمْ ۗ وَمَن يَكْفُرْ بِـَٔايَـٰتِ ٱللَّهِ فَإِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ","en":"Indeed, the religion in the sight of Allāh is Islām. And those who were given the Scripture did not differ except after knowledge had come to them - out of jealous animosity between themselves. And whoever disbelieves in the verses of Allāh, then indeed, Allāh is swift in [taking] account.","tr":"Inna addeena AAinda Allahial-islamu wama ikhtalafa allatheena ootooalkitaba illa min baAAdi ma jaahumualAAilmu baghyan baynahum waman yakfur bi-ayati Allahifa-inna Allaha sareeAAu alhisab","juz":3,"page":52},{"s":3,"a":20,"key":"3:20","ar":"فَإِنْ حَآجُّوكَ فَقُلْ أَسْلَمْتُ وَجْهِىَ لِلَّهِ وَمَنِ ٱتَّبَعَنِ ۗ وَقُل لِّلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ وَٱلْأُمِّيِّـۧنَ ءَأَسْلَمْتُمْ ۚ فَإِنْ أَسْلَمُوا۟ فَقَدِ ٱهْتَدَوا۟ ۖ وَّإِن تَوَلَّوْا۟ فَإِنَّمَا عَلَيْكَ ٱلْبَلَـٰغُ ۗ وَٱللَّهُ بَصِيرٌۢ بِٱلْعِبَادِ","en":"So if they argue with you, say, \"I have submitted myself to Allāh [in Islām], and [so have] those who follow me.\" And say to those who were given the Scripture and [to] the unlearned,1 \"Have you submitted yourselves?\" And if they submit [in Islām], they are rightly guided; but if they turn away - then upon you is only the [duty of] notification. And Allāh is Seeing of [His] servants.","tr":"Fa-in hajjooka faqul aslamtu wajhiyalillahi wamani ittabaAAani waqul lillatheena ootooalkitaba walommiyyeena aaslamtum fa-inaslamoo faqadi ihtadaw wa-in tawallaw fa-innama AAalaykaalbalaghu wallahu baseerun bilAAibad","juz":3,"page":52},{"s":3,"a":21,"key":"3:21","ar":"إِنَّ ٱلَّذِينَ يَكْفُرُونَ بِـَٔايَـٰتِ ٱللَّهِ وَيَقْتُلُونَ ٱلنَّبِيِّـۧنَ بِغَيْرِ حَقٍّ وَيَقْتُلُونَ ٱلَّذِينَ يَأْمُرُونَ بِٱلْقِسْطِ مِنَ ٱلنَّاسِ فَبَشِّرْهُم بِعَذَابٍ أَلِيمٍ","en":"Those who disbelieve in the signs of Allāh and kill the prophets without right and kill those who order justice from among the people - give them tidings of a painful punishment.","tr":"Inna allatheena yakfuroona bi-ayatiAllahi wayaqtuloona annabiyyeena bighayri haqqinwayaqtuloona allatheena ya/muroona bilqistimina annasi fabashshirhum biAAathabin aleem","juz":3,"page":52},{"s":3,"a":22,"key":"3:22","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ حَبِطَتْ أَعْمَـٰلُهُمْ فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ وَمَا لَهُم مِّن نَّـٰصِرِينَ","en":"They are the ones whose deeds have become worthless in this world and the Hereafter, and for them there will be no helpers.","tr":"Ola-ika allatheena habitataAAmaluhum fee addunya wal-akhiratiwama lahum min nasireen","juz":3,"page":52},{"s":3,"a":23,"key":"3:23","ar":"أَلَمْ تَرَ إِلَى ٱلَّذِينَ أُوتُوا۟ نَصِيبًا مِّنَ ٱلْكِتَـٰبِ يُدْعَوْنَ إِلَىٰ كِتَـٰبِ ٱللَّهِ لِيَحْكُمَ بَيْنَهُمْ ثُمَّ يَتَوَلَّىٰ فَرِيقٌ مِّنْهُمْ وَهُم مُّعْرِضُونَ","en":"Do you not consider, [O Muḥammad], those who were given a portion of the Scripture? They are invited to the Scripture of Allāh that it should arbitrate between them;1 then a party of them turns away, and they are refusing.","tr":"Alam tara ila allatheena ootoonaseeban mina alkitabi yudAAawna ila kitabiAllahi liyahkuma baynahum thumma yatawallafareequn minhum wahum muAAridoon","juz":3,"page":53},{"s":3,"a":24,"key":"3:24","ar":"ذَٰلِكَ بِأَنَّهُمْ قَالُوا۟ لَن تَمَسَّنَا ٱلنَّارُ إِلَّآ أَيَّامًا مَّعْدُودَٰتٍ ۖ وَغَرَّهُمْ فِى دِينِهِم مَّا كَانُوا۟ يَفْتَرُونَ","en":"That is because they say, \"Never will the Fire touch us except for [a few] numbered days,\" and [because] they were deluded in their religion by what they were inventing.","tr":"Thalika bi-annahum qaloo lantamassana annaru illa ayyamanmaAAdoodatin wagharrahum fee deenihim ma kanooyaftaroon","juz":3,"page":53},{"s":3,"a":25,"key":"3:25","ar":"فَكَيْفَ إِذَا جَمَعْنَـٰهُمْ لِيَوْمٍ لَّا رَيْبَ فِيهِ وَوُفِّيَتْ كُلُّ نَفْسٍ مَّا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ","en":"So how will it be when We assemble them for a Day about which there is no doubt? And each soul will be compensated [in full for] what it earned, and they will not be wronged.","tr":"Fakayfa itha jamaAAnahumliyawmin la rayba feehi wawuffiyat kullu nafsin makasabat wahum la yuthlamoon","juz":3,"page":53},{"s":3,"a":26,"key":"3:26","ar":"قُلِ ٱللَّهُمَّ مَـٰلِكَ ٱلْمُلْكِ تُؤْتِى ٱلْمُلْكَ مَن تَشَآءُ وَتَنزِعُ ٱلْمُلْكَ مِمَّن تَشَآءُ وَتُعِزُّ مَن تَشَآءُ وَتُذِلُّ مَن تَشَآءُ ۖ بِيَدِكَ ٱلْخَيْرُ ۖ إِنَّكَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Say, \"O Allāh, Owner of Sovereignty, You give sovereignty to whom You will and You take sovereignty away from whom You will. You honor whom You will and You humble whom You will. In Your hand1 is [all] good. Indeed, You are over all things competent.","tr":"Quli allahumma malika almulkitu/tee almulka man tashao watanziAAu almulka mimman tashaowatuAAizzu man tashao watuthillu man tashaobiyadika alkhayru innaka AAala kulli shay-in qadeer","juz":3,"page":53},{"s":3,"a":27,"key":"3:27","ar":"تُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَتُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ ۖ وَتُخْرِجُ ٱلْحَىَّ مِنَ ٱلْمَيِّتِ وَتُخْرِجُ ٱلْمَيِّتَ مِنَ ٱلْحَىِّ ۖ وَتَرْزُقُ مَن تَشَآءُ بِغَيْرِ حِسَابٍ","en":"You cause the night to enter the day, and You cause the day to enter the night; and You bring the living out of the dead, and You bring the dead out of the living. And You give provision to whom You will without account [i.e., limit or measure].\"","tr":"Tooliju allayla fee annahariwatooliju annahara fee allayli watukhriju alhayyamina almayyiti watukhriju almayyita mina alhayyi watarzuquman tashao bighayri hisab","juz":3,"page":53},{"s":3,"a":28,"key":"3:28","ar":"لَّا يَتَّخِذِ ٱلْمُؤْمِنُونَ ٱلْكَـٰفِرِينَ أَوْلِيَآءَ مِن دُونِ ٱلْمُؤْمِنِينَ ۖ وَمَن يَفْعَلْ ذَٰلِكَ فَلَيْسَ مِنَ ٱللَّهِ فِى شَىْءٍ إِلَّآ أَن تَتَّقُوا۟ مِنْهُمْ تُقَىٰةً ۗ وَيُحَذِّرُكُمُ ٱللَّهُ نَفْسَهُۥ ۗ وَإِلَى ٱللَّهِ ٱلْمَصِيرُ","en":"Let not believers take disbelievers as allies [i.e., supporters or protectors] rather than believers. And whoever [of you] does that has nothing [i.e., no association] with Allāh, except when taking precaution against them in prudence.1 And Allāh warns you of Himself, and to Allāh is the [final] destination.","tr":"La yattakhithi almu/minoonaalkafireena awliyaa min dooni almu/mineena wamanyafAAal thalika falaysa mina Allahi fee shay-in illaan tattaqoo minhum tuqatan wayuhaththirukumuAllahu nafsahu wa-ila Allahi almaseer","juz":3,"page":53},{"s":3,"a":29,"key":"3:29","ar":"قُلْ إِن تُخْفُوا۟ مَا فِى صُدُورِكُمْ أَوْ تُبْدُوهُ يَعْلَمْهُ ٱللَّهُ ۗ وَيَعْلَمُ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Say, \"Whether you conceal what is in your breasts or reveal it, Allāh knows it. And He knows that which is in the heavens and that which is on the earth. And Allāh is over all things competent.","tr":"Qul in tukhfoo ma fee sudoorikumaw tubdoohu yaAAlamhu Allahu wayaAAlamu ma fee assamawatiwama fee al-ardi wallahu AAalakulli shay-in qadeer","juz":3,"page":53},{"s":3,"a":30,"key":"3:30","ar":"يَوْمَ تَجِدُ كُلُّ نَفْسٍ مَّا عَمِلَتْ مِنْ خَيْرٍ مُّحْضَرًا وَمَا عَمِلَتْ مِن سُوٓءٍ تَوَدُّ لَوْ أَنَّ بَيْنَهَا وَبَيْنَهُۥٓ أَمَدًۢا بَعِيدًا ۗ وَيُحَذِّرُكُمُ ٱللَّهُ نَفْسَهُۥ ۗ وَٱللَّهُ رَءُوفٌۢ بِٱلْعِبَادِ","en":"The Day every soul will find what it has done of good present [before it] and what it has done of evil, it will wish that between itself and that [evil] was a great distance. And Allāh warns you of Himself, and Allāh is Kind to [His] servants.\"","tr":"Yawma tajidu kullu nafsin ma AAamilatmin khayrin muhdaran wama AAamilat min soo-intawaddu law anna baynaha wabaynahu amadan baAAeedan wayuhaththirukumuAllahu nafsahu wallahu raoofun bilAAibad","juz":3,"page":54},{"s":3,"a":31,"key":"3:31","ar":"قُلْ إِن كُنتُمْ تُحِبُّونَ ٱللَّهَ فَٱتَّبِعُونِى يُحْبِبْكُمُ ٱللَّهُ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ ۗ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"Say, [O Muḥammad], \"If you should love Allāh, then follow me, [so] Allāh will love you and forgive you your sins. And Allāh is Forgiving and Merciful.\"","tr":"Qul in kuntum tuhibboona AllahafattabiAAoonee yuhbibkumu Allahu wayaghfirlakum thunoobakum wallahu ghafoorun raheem","juz":3,"page":54},{"s":3,"a":32,"key":"3:32","ar":"قُلْ أَطِيعُوا۟ ٱللَّهَ وَٱلرَّسُولَ ۖ فَإِن تَوَلَّوْا۟ فَإِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْكَـٰفِرِينَ","en":"Say, \"Obey Allāh and the Messenger. But if you turn away - then indeed, Allāh does not like the disbelievers.\"","tr":"Qul ateeAAoo Allaha warrasoolafa-in tawallaw fa-inna Allaha la yuhibbu alkafireen","juz":3,"page":54},{"s":3,"a":33,"key":"3:33","ar":"۞ إِنَّ ٱللَّهَ ٱصْطَفَىٰٓ ءَادَمَ وَنُوحًا وَءَالَ إِبْرَٰهِيمَ وَءَالَ عِمْرَٰنَ عَلَى ٱلْعَـٰلَمِينَ","en":"Indeed, Allāh chose Adam and Noah and the family of Abraham and the family of ʿImrān over the worlds -","tr":"Inna Allaha istafa adamawanoohan waala ibraheema waala AAimranaAAala alAAalameen","juz":3,"page":54},{"s":3,"a":34,"key":"3:34","ar":"ذُرِّيَّةًۢ بَعْضُهَا مِنۢ بَعْضٍ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ","en":"Descendants, some of them from others. And Allāh is Hearing and Knowing.","tr":"Thurriyyatan baAAduhamin baAAdin wallahu sameeAAun AAaleem","juz":3,"page":54},{"s":3,"a":35,"key":"3:35","ar":"إِذْ قَالَتِ ٱمْرَأَتُ عِمْرَٰنَ رَبِّ إِنِّى نَذَرْتُ لَكَ مَا فِى بَطْنِى مُحَرَّرًا فَتَقَبَّلْ مِنِّىٓ ۖ إِنَّكَ أَنتَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"[Mention, O Muḥammad], when the wife of ʿImrān said, \"My Lord, indeed I have pledged to You what is in my womb, consecrated [for Your service], so accept this from me. Indeed, You are the Hearing, the Knowing.\"","tr":"Ith qalati imraatu AAimranarabbi innee nathartu laka ma fee batnee muharraranfataqabbal minnee innaka anta assameeAAu alAAaleem","juz":3,"page":54},{"s":3,"a":36,"key":"3:36","ar":"فَلَمَّا وَضَعَتْهَا قَالَتْ رَبِّ إِنِّى وَضَعْتُهَآ أُنثَىٰ وَٱللَّهُ أَعْلَمُ بِمَا وَضَعَتْ وَلَيْسَ ٱلذَّكَرُ كَٱلْأُنثَىٰ ۖ وَإِنِّى سَمَّيْتُهَا مَرْيَمَ وَإِنِّىٓ أُعِيذُهَا بِكَ وَذُرِّيَّتَهَا مِنَ ٱلشَّيْطَـٰنِ ٱلرَّجِيمِ","en":"But when she delivered her, she said, \"My Lord, I have delivered a female.\" And Allāh was most knowing of what she delivered, and the male is not like the female. \"And I have named her Mary, and I seek refuge for her in You and [for] her descendants from Satan, the expelled [from the mercy of Allāh].\"","tr":"Falamma wadaAAat-ha qalatrabbi innee wadaAAtuha ontha wallahuaAAlamu bima wadaAAat walaysa aththakarukalontha wa-innee sammaytuha maryamawa-innee oAAeethuha bika wathurriyyatahamina ashshaytani arrajeem","juz":3,"page":54},{"s":3,"a":37,"key":"3:37","ar":"فَتَقَبَّلَهَا رَبُّهَا بِقَبُولٍ حَسَنٍ وَأَنۢبَتَهَا نَبَاتًا حَسَنًا وَكَفَّلَهَا زَكَرِيَّا ۖ كُلَّمَا دَخَلَ عَلَيْهَا زَكَرِيَّا ٱلْمِحْرَابَ وَجَدَ عِندَهَا رِزْقًا ۖ قَالَ يَـٰمَرْيَمُ أَنَّىٰ لَكِ هَـٰذَا ۖ قَالَتْ هُوَ مِنْ عِندِ ٱللَّهِ ۖ إِنَّ ٱللَّهَ يَرْزُقُ مَن يَشَآءُ بِغَيْرِ حِسَابٍ","en":"So her Lord accepted her with good acceptance and caused her to grow in a good manner and put her in the care of Zechariah. Every time Zechariah entered upon her in the prayer chamber, he found with her provision. He said, \"O Mary, from where is this [coming] to you?\" She said, \"It is from Allāh. Indeed, Allāh provides for whom He wills without account.\"","tr":"Fataqabbalaha rabbuhabiqaboolin hasanin waanbataha nabatan hasananwakaffalaha zakariyya kullama dakhalaAAalayha zakariyya almihraba wajadaAAindaha rizqan qala ya maryamu annalaki hatha qalat huwa min AAindi Allahi innaAllaha yarzuqu man yashao bighayri hisab","juz":3,"page":54},{"s":3,"a":38,"key":"3:38","ar":"هُنَالِكَ دَعَا زَكَرِيَّا رَبَّهُۥ ۖ قَالَ رَبِّ هَبْ لِى مِن لَّدُنكَ ذُرِّيَّةً طَيِّبَةً ۖ إِنَّكَ سَمِيعُ ٱلدُّعَآءِ","en":"At that, Zechariah called upon his Lord, saying, \"My Lord, grant me from Yourself a good offspring. Indeed, You are the Hearer of supplication.\"","tr":"Hunalika daAAa zakariyyarabbahu qala rabbi hab lee min ladunka thurriyyatantayyibatan innaka sameeAAu adduAAa/-","juz":3,"page":55},{"s":3,"a":39,"key":"3:39","ar":"فَنَادَتْهُ ٱلْمَلَـٰٓئِكَةُ وَهُوَ قَآئِمٌ يُصَلِّى فِى ٱلْمِحْرَابِ أَنَّ ٱللَّهَ يُبَشِّرُكَ بِيَحْيَىٰ مُصَدِّقًۢا بِكَلِمَةٍ مِّنَ ٱللَّهِ وَسَيِّدًا وَحَصُورًا وَنَبِيًّا مِّنَ ٱلصَّـٰلِحِينَ","en":"So the angels called him while he was standing in prayer in the chamber, \"Indeed, Allāh gives you good tidings of John, confirming a word1 from Allāh and [who will be] honorable, abstaining [from women], and a prophet from among the righteous.\"","tr":"Fanadat-hu almala-ikatu wahuwaqa-imun yusallee fee almihrabi annaAllaha yubashshiruka biyahya musaddiqanbikalimatin mina Allahi wasayyidan wahasooranwanabiyyan mina assaliheen","juz":3,"page":55},{"s":3,"a":40,"key":"3:40","ar":"قَالَ رَبِّ أَنَّىٰ يَكُونُ لِى غُلَـٰمٌ وَقَدْ بَلَغَنِىَ ٱلْكِبَرُ وَٱمْرَأَتِى عَاقِرٌ ۖ قَالَ كَذَٰلِكَ ٱللَّهُ يَفْعَلُ مَا يَشَآءُ","en":"He said, \"My Lord, how will I have a boy when I have reached old age and my wife is barren?\" He [the angel] said, \"Such is Allāh; He does what He wills.\"","tr":"Qala rabbi anna yakoonu leeghulamun waqad balaghaniya alkibaru wamraatee AAaqirunqala kathalika Allahu yafAAalu mayasha/","juz":3,"page":55},{"s":3,"a":41,"key":"3:41","ar":"قَالَ رَبِّ ٱجْعَل لِّىٓ ءَايَةً ۖ قَالَ ءَايَتُكَ أَلَّا تُكَلِّمَ ٱلنَّاسَ ثَلَـٰثَةَ أَيَّامٍ إِلَّا رَمْزًا ۗ وَٱذْكُر رَّبَّكَ كَثِيرًا وَسَبِّحْ بِٱلْعَشِىِّ وَٱلْإِبْكَـٰرِ","en":"He said, \"My Lord, make for me a sign.\" He said, \"Your sign is that you will not [be able to] speak to the people for three days except by gesture. And remember your Lord much and exalt [Him with praise] in the evening and the morning.\"","tr":"Qala rabbi ijAAal lee ayatan qalaayatuka alla tukallima annasa thalathataayyamin illa ramzan wathkur rabbakakatheeran wasabbih bilAAashiyyi wal-ibkar","juz":3,"page":55},{"s":3,"a":42,"key":"3:42","ar":"وَإِذْ قَالَتِ ٱلْمَلَـٰٓئِكَةُ يَـٰمَرْيَمُ إِنَّ ٱللَّهَ ٱصْطَفَىٰكِ وَطَهَّرَكِ وَٱصْطَفَىٰكِ عَلَىٰ نِسَآءِ ٱلْعَـٰلَمِينَ","en":"And [mention] when the angels said, \"O Mary, indeed Allāh has chosen you and purified you and chosen you above the women of the worlds.","tr":"Wa-ith qalati almala-ikatuya maryamu inna Allaha istafaki watahharakiwastafaki AAala nisa-i alAAalameen","juz":3,"page":55},{"s":3,"a":43,"key":"3:43","ar":"يَـٰمَرْيَمُ ٱقْنُتِى لِرَبِّكِ وَٱسْجُدِى وَٱرْكَعِى مَعَ ٱلرَّٰكِعِينَ","en":"O Mary, be devoutly obedient to your Lord and prostrate and bow with those who bow [in prayer].\"","tr":"Ya maryamu oqnutee lirabbiki wasjudeewarkaAAee maAAa arrakiAAeen","juz":3,"page":55},{"s":3,"a":44,"key":"3:44","ar":"ذَٰلِكَ مِنْ أَنۢبَآءِ ٱلْغَيْبِ نُوحِيهِ إِلَيْكَ ۚ وَمَا كُنتَ لَدَيْهِمْ إِذْ يُلْقُونَ أَقْلَـٰمَهُمْ أَيُّهُمْ يَكْفُلُ مَرْيَمَ وَمَا كُنتَ لَدَيْهِمْ إِذْ يَخْتَصِمُونَ","en":"That is from the news of the unseen which We reveal to you, [O Muḥammad]. And you were not with them when they cast their pens1 as to which of them should be responsible for Mary. Nor were you with them when they disputed.","tr":"Thalika min anba-i alghaybinooheehi ilayka wama kunta ladayhim ithyulqoona aqlamahum ayyuhum yakfulu maryama wamakunta ladayhim ith yakhtasimoon","juz":3,"page":55},{"s":3,"a":45,"key":"3:45","ar":"إِذْ قَالَتِ ٱلْمَلَـٰٓئِكَةُ يَـٰمَرْيَمُ إِنَّ ٱللَّهَ يُبَشِّرُكِ بِكَلِمَةٍ مِّنْهُ ٱسْمُهُ ٱلْمَسِيحُ عِيسَى ٱبْنُ مَرْيَمَ وَجِيهًا فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ وَمِنَ ٱلْمُقَرَّبِينَ","en":"[And mention] when the angels said, \"O Mary, indeed Allāh gives you good tidings of a word1 from Him, whose name will be the Messiah, Jesus, the son of Mary - distinguished in this world and the Hereafter and among those brought near [to Allāh].","tr":"Ith qalati almala-ikatuya maryamu inna Allaha yubashshiruki bikalimatinminhu ismuhu almaseehu AAeesa ibnu maryama wajeehanfee addunya wal-akhirati waminaalmuqarrabeen","juz":3,"page":55},{"s":3,"a":46,"key":"3:46","ar":"وَيُكَلِّمُ ٱلنَّاسَ فِى ٱلْمَهْدِ وَكَهْلًا وَمِنَ ٱلصَّـٰلِحِينَ","en":"He will speak to the people in the cradle and in maturity and will be of the righteous.\"","tr":"Wayukallimu annasa feealmahdi wakahlan wamina assaliheen","juz":3,"page":56},{"s":3,"a":47,"key":"3:47","ar":"قَالَتْ رَبِّ أَنَّىٰ يَكُونُ لِى وَلَدٌ وَلَمْ يَمْسَسْنِى بَشَرٌ ۖ قَالَ كَذَٰلِكِ ٱللَّهُ يَخْلُقُ مَا يَشَآءُ ۚ إِذَا قَضَىٰٓ أَمْرًا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ","en":"She said, \"My Lord, how will I have a child when no man has touched me?\" [The angel] said, \"Such is Allāh; He creates what He wills. When He decrees a matter, He only says to it, 'Be,' and it is.","tr":"Qalat rabbi anna yakoonu leewaladun walam yamsasnee basharun qala kathaliki Allahuyakhluqu ma yashao itha qada amranfa-innama yaqoolu lahu kun fayakoon","juz":3,"page":56},{"s":3,"a":48,"key":"3:48","ar":"وَيُعَلِّمُهُ ٱلْكِتَـٰبَ وَٱلْحِكْمَةَ وَٱلتَّوْرَىٰةَ وَٱلْإِنجِيلَ","en":"And He will teach him writing and wisdom1 and the Torah and the Gospel","tr":"WayuAAallimuhu alkitaba walhikmatawattawrata wal-injeel","juz":3,"page":56},{"s":3,"a":49,"key":"3:49","ar":"وَرَسُولًا إِلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ أَنِّى قَدْ جِئْتُكُم بِـَٔايَةٍ مِّن رَّبِّكُمْ ۖ أَنِّىٓ أَخْلُقُ لَكُم مِّنَ ٱلطِّينِ كَهَيْـَٔةِ ٱلطَّيْرِ فَأَنفُخُ فِيهِ فَيَكُونُ طَيْرًۢا بِإِذْنِ ٱللَّهِ ۖ وَأُبْرِئُ ٱلْأَكْمَهَ وَٱلْأَبْرَصَ وَأُحْىِ ٱلْمَوْتَىٰ بِإِذْنِ ٱللَّهِ ۖ وَأُنَبِّئُكُم بِمَا تَأْكُلُونَ وَمَا تَدَّخِرُونَ فِى بُيُوتِكُمْ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ","en":"And [make him] a messenger to the Children of Israel, [who will say], 'Indeed I have come to you with a sign from your Lord in that I design for you from clay [that which is] like the form of a bird, then I breathe into it and it becomes a bird by permission of Allāh. And I cure the blind [from birth] and the leper, and I give life to the dead - by permission of Allāh. And I inform you of what you eat and what you store in your houses. Indeed in that is a sign for you, if you are believers.","tr":"Warasoolan ila banee isra-eelaannee qad ji/tukum bi-ayatin min rabbikum annee akhluqulakum mina atteeni kahay-ati attayrifaanfukhu feehi fayakoonu tayran bi-ithni Allahiwaobri-o al-akmaha wal-abrasa waohyeealmawta bi-ithni Allahi waonabbi-okum bimata/kuloona wama taddakhiroona fee buyootikum inna fee thalikalaayatan lakum in kuntum mu/mineen","juz":3,"page":56},{"s":3,"a":50,"key":"3:50","ar":"وَمُصَدِّقًا لِّمَا بَيْنَ يَدَىَّ مِنَ ٱلتَّوْرَىٰةِ وَلِأُحِلَّ لَكُم بَعْضَ ٱلَّذِى حُرِّمَ عَلَيْكُمْ ۚ وَجِئْتُكُم بِـَٔايَةٍ مِّن رَّبِّكُمْ فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"And [I have come] confirming what was before me of the Torah and to make lawful for you some of what was forbidden to you. And I have come to you with a sign from your Lord, so fear Allāh and obey me.","tr":"Wamusaddiqan lima baynayadayya mina attawrati wali-ohilla lakumbaAAda allathee hurrima AAalaykum waji/tukumbi-ayatin min rabbikum fattaqoo Allaha waateeAAoon","juz":3,"page":56},{"s":3,"a":51,"key":"3:51","ar":"إِنَّ ٱللَّهَ رَبِّى وَرَبُّكُمْ فَٱعْبُدُوهُ ۗ هَـٰذَا صِرَٰطٌ مُّسْتَقِيمٌ","en":"Indeed, Allāh is my Lord and your Lord, so worship Him. That is the straight path.'\"","tr":"Inna Allaha rabbee warabbukum faAAbudoohuhatha siratun mustaqeem","juz":3,"page":56},{"s":3,"a":52,"key":"3:52","ar":"۞ فَلَمَّآ أَحَسَّ عِيسَىٰ مِنْهُمُ ٱلْكُفْرَ قَالَ مَنْ أَنصَارِىٓ إِلَى ٱللَّهِ ۖ قَالَ ٱلْحَوَارِيُّونَ نَحْنُ أَنصَارُ ٱللَّهِ ءَامَنَّا بِٱللَّهِ وَٱشْهَدْ بِأَنَّا مُسْلِمُونَ","en":"But when Jesus felt [persistence in] disbelief from them, he said, \"Who are my supporters for [the cause of] Allāh?\" The disciples said, \"We are supporters for Allāh. We have believed in Allāh and testify that we are Muslims [submitting to Him].","tr":"Falamma ahassa AAeesaminhumu alkufra qala man ansaree ila Allahiqala alhawariyyoona nahnu ansaruAllahi amanna billahi washhadbi-anna muslimoon","juz":3,"page":56},{"s":3,"a":53,"key":"3:53","ar":"رَبَّنَآ ءَامَنَّا بِمَآ أَنزَلْتَ وَٱتَّبَعْنَا ٱلرَّسُولَ فَٱكْتُبْنَا مَعَ ٱلشَّـٰهِدِينَ","en":"Our Lord, we have believed in what You revealed and have followed the messenger [i.e., Jesus], so register us among the witnesses [to truth].\"","tr":"Rabbana amanna bimaanzalta wattabaAAna arrasoola faktubnamaAAa ashshahideen","juz":3,"page":57},{"s":3,"a":54,"key":"3:54","ar":"وَمَكَرُوا۟ وَمَكَرَ ٱللَّهُ ۖ وَٱللَّهُ خَيْرُ ٱلْمَـٰكِرِينَ","en":"And they [i.e., the disbelievers] planned, but Allāh planned. And Allāh is the best of planners.","tr":"Wamakaroo wamakara Allahu wallahukhayru almakireen","juz":3,"page":57},{"s":3,"a":55,"key":"3:55","ar":"إِذْ قَالَ ٱللَّهُ يَـٰعِيسَىٰٓ إِنِّى مُتَوَفِّيكَ وَرَافِعُكَ إِلَىَّ وَمُطَهِّرُكَ مِنَ ٱلَّذِينَ كَفَرُوا۟ وَجَاعِلُ ٱلَّذِينَ ٱتَّبَعُوكَ فَوْقَ ٱلَّذِينَ كَفَرُوٓا۟ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ ۖ ثُمَّ إِلَىَّ مَرْجِعُكُمْ فَأَحْكُمُ بَيْنَكُمْ فِيمَا كُنتُمْ فِيهِ تَخْتَلِفُونَ","en":"[Mention] when Allāh said, \"O Jesus, indeed I will take you and raise you to Myself and purify [i.e., free] you from those who disbelieve and make those who follow you [in submission to Allāh alone] superior to those who disbelieve until the Day of Resurrection. Then to Me is your return, and I will judge between you concerning that in which you used to differ.","tr":"Ith qala Allahu yaAAeesa innee mutawaffeeka warafiAAuka ilayya wamutahhirukamina allatheena kafaroo wajaAAilu allatheenaittabaAAooka fawqa allatheena kafaroo ila yawmialqiyamati thumma ilayya marjiAAukum faahkumubaynakum feema kuntum feehi takhtalifoon","juz":3,"page":57},{"s":3,"a":56,"key":"3:56","ar":"فَأَمَّا ٱلَّذِينَ كَفَرُوا۟ فَأُعَذِّبُهُمْ عَذَابًا شَدِيدًا فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ وَمَا لَهُم مِّن نَّـٰصِرِينَ","en":"And as for those who disbelieved, I will punish them with a severe punishment in this world and the Hereafter, and they will have no helpers.\"","tr":"Faamma allatheena kafaroofaoAAaththibuhum AAathaban shadeedan fee addunyawal-akhirati wama lahum min nasireen","juz":3,"page":57},{"s":3,"a":57,"key":"3:57","ar":"وَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ فَيُوَفِّيهِمْ أُجُورَهُمْ ۗ وَٱللَّهُ لَا يُحِبُّ ٱلظَّـٰلِمِينَ","en":"But as for those who believed and did righteous deeds, He will give them in full their rewards, and Allāh does not like the wrongdoers.","tr":"Waamma allatheena amanoowaAAamiloo assalihati fayuwaffeehimojoorahum wallahu la yuhibbu aththalimeen","juz":3,"page":57},{"s":3,"a":58,"key":"3:58","ar":"ذَٰلِكَ نَتْلُوهُ عَلَيْكَ مِنَ ٱلْـَٔايَـٰتِ وَٱلذِّكْرِ ٱلْحَكِيمِ","en":"This is what We recite to you, [O Muḥammad], of [Our] verses and the precise [and wise] message [i.e., the Qur’ān].","tr":"Thalika natloohu AAalayka mina al-ayatiwaththikri alhakeem","juz":3,"page":57},{"s":3,"a":59,"key":"3:59","ar":"إِنَّ مَثَلَ عِيسَىٰ عِندَ ٱللَّهِ كَمَثَلِ ءَادَمَ ۖ خَلَقَهُۥ مِن تُرَابٍ ثُمَّ قَالَ لَهُۥ كُن فَيَكُونُ","en":"Indeed, the example of Jesus to Allāh1 is like that of Adam. He created him from dust; then He said to him, \"Be,\" and he was.","tr":"Inna mathala AAeesa AAinda Allahikamathali adama khalaqahu min turabin thumma qalalahu kun fayakoon","juz":3,"page":57},{"s":3,"a":60,"key":"3:60","ar":"ٱلْحَقُّ مِن رَّبِّكَ فَلَا تَكُن مِّنَ ٱلْمُمْتَرِينَ","en":"The truth is from your Lord, so do not be among the doubters.","tr":"Alhaqqu min rabbika fala takunmina almumtareen","juz":3,"page":57},{"s":3,"a":61,"key":"3:61","ar":"فَمَنْ حَآجَّكَ فِيهِ مِنۢ بَعْدِ مَا جَآءَكَ مِنَ ٱلْعِلْمِ فَقُلْ تَعَالَوْا۟ نَدْعُ أَبْنَآءَنَا وَأَبْنَآءَكُمْ وَنِسَآءَنَا وَنِسَآءَكُمْ وَأَنفُسَنَا وَأَنفُسَكُمْ ثُمَّ نَبْتَهِلْ فَنَجْعَل لَّعْنَتَ ٱللَّهِ عَلَى ٱلْكَـٰذِبِينَ","en":"Then whoever argues with you about it after [this] knowledge has come to you - say, \"Come, let us call our sons and your sons, our women and your women, ourselves and yourselves, then supplicate earnestly [together] and invoke the curse of Allāh upon the liars [among us].\"","tr":"Faman hajjaka feehi min baAAdi majaaka mina alAAilmi faqul taAAalaw nadAAu abnaanawaabnaakum wanisaana wanisaakumwaanfusana waanfusakum thumma nabtahil fanajAAal laAAnataAllahi AAala alkathibeen","juz":3,"page":57},{"s":3,"a":62,"key":"3:62","ar":"إِنَّ هَـٰذَا لَهُوَ ٱلْقَصَصُ ٱلْحَقُّ ۚ وَمَا مِنْ إِلَـٰهٍ إِلَّا ٱللَّهُ ۚ وَإِنَّ ٱللَّهَ لَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Indeed, this is the true narration. And there is no deity except Allāh. And indeed, Allāh is the Exalted in Might, the Wise.","tr":"Inna hatha lahuwa alqasasualhaqqu wama min ilahin illa Allahuwa-inna Allaha lahuwa alAAazeezu alhakeem","juz":3,"page":58},{"s":3,"a":63,"key":"3:63","ar":"فَإِن تَوَلَّوْا۟ فَإِنَّ ٱللَّهَ عَلِيمٌۢ بِٱلْمُفْسِدِينَ","en":"But if they turn away, then indeed - Allāh is Knowing of the corrupters.","tr":"Fa-in tawallaw fa-inna AllahaAAaleemun bilmufsideen","juz":3,"page":58},{"s":3,"a":64,"key":"3:64","ar":"قُلْ يَـٰٓأَهْلَ ٱلْكِتَـٰبِ تَعَالَوْا۟ إِلَىٰ كَلِمَةٍ سَوَآءٍۭ بَيْنَنَا وَبَيْنَكُمْ أَلَّا نَعْبُدَ إِلَّا ٱللَّهَ وَلَا نُشْرِكَ بِهِۦ شَيْـًٔا وَلَا يَتَّخِذَ بَعْضُنَا بَعْضًا أَرْبَابًا مِّن دُونِ ٱللَّهِ ۚ فَإِن تَوَلَّوْا۟ فَقُولُوا۟ ٱشْهَدُوا۟ بِأَنَّا مُسْلِمُونَ","en":"Say, \"O People of the Scripture, come to a word that is equitable between us and you - that we will not worship except Allāh and not associate anything with Him and not take one another as lords instead of Allāh.\"1 But if they turn away, then say, \"Bear witness that we are Muslims [submitting to Him].\"","tr":"Qul ya ahla alkitabi taAAalawila kalimatin sawa-in baynana wabaynakum allanaAAbuda illa Allaha wala nushrika bihishay-an wala yattakhitha baAAdunabaAAdan arbaban min dooni Allahi fa-intawallaw faqooloo ishhadoo bi-anna muslimoon","juz":3,"page":58},{"s":3,"a":65,"key":"3:65","ar":"يَـٰٓأَهْلَ ٱلْكِتَـٰبِ لِمَ تُحَآجُّونَ فِىٓ إِبْرَٰهِيمَ وَمَآ أُنزِلَتِ ٱلتَّوْرَىٰةُ وَٱلْإِنجِيلُ إِلَّا مِنۢ بَعْدِهِۦٓ ۚ أَفَلَا تَعْقِلُونَ","en":"O People of the Scripture, why do you argue about Abraham while the Torah and the Gospel were not revealed until after him? Then will you not reason?","tr":"Ya ahla alkitabi lima tuhajjoonafee ibraheema wama onzilati attawratuwal-injeelu illa min baAAdihi afalataAAqiloon","juz":3,"page":58},{"s":3,"a":66,"key":"3:66","ar":"هَـٰٓأَنتُمْ هَـٰٓؤُلَآءِ حَـٰجَجْتُمْ فِيمَا لَكُم بِهِۦ عِلْمٌ فَلِمَ تُحَآجُّونَ فِيمَا لَيْسَ لَكُم بِهِۦ عِلْمٌ ۚ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ","en":"Here you are - those who have argued about that of which you have [some] knowledge, but why do you argue about that of which you have no knowledge? And Allāh knows, while you know not.","tr":"Ha antum haola-i hajajtumfeema lakum bihi AAilmun falima tuhajjoona feemalaysa lakum bihi AAilmun wallahu yaAAlamu waantumla taAAlamoon","juz":3,"page":58},{"s":3,"a":67,"key":"3:67","ar":"مَا كَانَ إِبْرَٰهِيمُ يَهُودِيًّا وَلَا نَصْرَانِيًّا وَلَـٰكِن كَانَ حَنِيفًا مُّسْلِمًا وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ","en":"Abraham was neither a Jew nor a Christian, but he was one inclining toward truth, a Muslim [submitting to Allāh]. And he was not of the polytheists.1","tr":"Ma kana ibraheemuyahoodiyyan wala nasraniyyan walakinkana haneefan musliman wama kana minaalmushrikeen","juz":3,"page":58},{"s":3,"a":68,"key":"3:68","ar":"إِنَّ أَوْلَى ٱلنَّاسِ بِإِبْرَٰهِيمَ لَلَّذِينَ ٱتَّبَعُوهُ وَهَـٰذَا ٱلنَّبِىُّ وَٱلَّذِينَ ءَامَنُوا۟ ۗ وَٱللَّهُ وَلِىُّ ٱلْمُؤْمِنِينَ","en":"Indeed, the most worthy of Abraham among the people are those who followed him [in submission to Allāh] and this prophet [i.e., Muḥammad (ﷺ)] and those who believe [in his message]. And Allāh is the Ally1 of the believers.","tr":"Inna awla annasibi-ibraheema lallatheena ittabaAAoohu wahathaannabiyyu wallatheena amanoo wallahuwaliyyu almu/mineen","juz":3,"page":58},{"s":3,"a":69,"key":"3:69","ar":"وَدَّت طَّآئِفَةٌ مِّنْ أَهْلِ ٱلْكِتَـٰبِ لَوْ يُضِلُّونَكُمْ وَمَا يُضِلُّونَ إِلَّآ أَنفُسَهُمْ وَمَا يَشْعُرُونَ","en":"A faction of the People of the Scripture wish they could mislead you. But they do not mislead except themselves, and they perceive [it] not.","tr":"Waddat ta-ifatun min ahli alkitabilaw yudilloonakum wama yudilloona illaanfusahum wama yashAAuroon","juz":3,"page":58},{"s":3,"a":70,"key":"3:70","ar":"يَـٰٓأَهْلَ ٱلْكِتَـٰبِ لِمَ تَكْفُرُونَ بِـَٔايَـٰتِ ٱللَّهِ وَأَنتُمْ تَشْهَدُونَ","en":"O People of the Scripture, why do you disbelieve in the verses of Allāh1 while you witness [to their truth]?","tr":"Ya ahla alkitabi limatakfuroona bi-ayati Allahi waantumtashhadoon","juz":3,"page":58},{"s":3,"a":71,"key":"3:71","ar":"يَـٰٓأَهْلَ ٱلْكِتَـٰبِ لِمَ تَلْبِسُونَ ٱلْحَقَّ بِٱلْبَـٰطِلِ وَتَكْتُمُونَ ٱلْحَقَّ وَأَنتُمْ تَعْلَمُونَ","en":"O People of the Scripture, why do you mix [i.e., confuse] the truth with falsehood and conceal the truth while you know [it]?","tr":"Ya ahla alkitabi limatalbisoona alhaqqa bilbatili wataktumoonaalhaqqa waantum taAAlamoon","juz":3,"page":59},{"s":3,"a":72,"key":"3:72","ar":"وَقَالَت طَّآئِفَةٌ مِّنْ أَهْلِ ٱلْكِتَـٰبِ ءَامِنُوا۟ بِٱلَّذِىٓ أُنزِلَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَجْهَ ٱلنَّهَارِ وَٱكْفُرُوٓا۟ ءَاخِرَهُۥ لَعَلَّهُمْ يَرْجِعُونَ","en":"And a faction of the People of the Scripture say [to each other], \"Believe in that which was revealed to the believers at the beginning of the day and reject it at its end that perhaps they will return [i.e., abandon their religion],","tr":"Waqalat ta-ifatun min ahlialkitabi aminoo billathee onzilaAAala allatheena amanoo wajha annahariwakfuroo akhirahu laAAallahum yarjiAAoon","juz":3,"page":59},{"s":3,"a":73,"key":"3:73","ar":"وَلَا تُؤْمِنُوٓا۟ إِلَّا لِمَن تَبِعَ دِينَكُمْ قُلْ إِنَّ ٱلْهُدَىٰ هُدَى ٱللَّهِ أَن يُؤْتَىٰٓ أَحَدٌ مِّثْلَ مَآ أُوتِيتُمْ أَوْ يُحَآجُّوكُمْ عِندَ رَبِّكُمْ ۗ قُلْ إِنَّ ٱلْفَضْلَ بِيَدِ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ","en":"And do not trust except those who follow your religion.\" Say, \"Indeed, the [true] guidance is the guidance of Allāh. [Do you fear] lest someone be given [knowledge] like you were given or that they would [thereby] argue with you before your Lord?\" Say, \"Indeed, [all] bounty is in the hand1 of Allāh - He grants it to whom He wills. And Allāh is all-Encompassing and Wise.\"","tr":"Wala tu/minoo illa limantabiAAa deenakum qul inna alhuda huda Allahian yu/ta ahadun mithla ma ooteetum aw yuhajjookumAAinda rabbikum qul inna alfadla biyadi Allahiyu/teehi man yashao wallahu wasiAAunAAaleem","juz":3,"page":59},{"s":3,"a":74,"key":"3:74","ar":"يَخْتَصُّ بِرَحْمَتِهِۦ مَن يَشَآءُ ۗ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ","en":"He selects for His mercy whom He wills. And Allāh is the possessor of great bounty.","tr":"Yakhtassu birahmatihi man yashaowallahu thoo alfadli alAAatheem","juz":3,"page":59},{"s":3,"a":75,"key":"3:75","ar":"۞ وَمِنْ أَهْلِ ٱلْكِتَـٰبِ مَنْ إِن تَأْمَنْهُ بِقِنطَارٍ يُؤَدِّهِۦٓ إِلَيْكَ وَمِنْهُم مَّنْ إِن تَأْمَنْهُ بِدِينَارٍ لَّا يُؤَدِّهِۦٓ إِلَيْكَ إِلَّا مَا دُمْتَ عَلَيْهِ قَآئِمًا ۗ ذَٰلِكَ بِأَنَّهُمْ قَالُوا۟ لَيْسَ عَلَيْنَا فِى ٱلْأُمِّيِّـۧنَ سَبِيلٌ وَيَقُولُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ وَهُمْ يَعْلَمُونَ","en":"And among the People of the Scripture is he who, if you entrust him with a great amount [of wealth], he will return it to you. And among them is he who, if you entrust him with a [single] coin, he will not return it to you unless you are constantly standing over him [demanding it]. That is because they say, \"There is no blame upon us concerning the unlearned.\"1 And they speak untruth about Allāh while they know [it].","tr":"Wamin ahli alkitabi man in ta/manhubiqintarin yu-addihi ilayka waminhum man in ta/manhubideenarin la yu-addihi ilayka illa madumta AAalayhi qa-iman thalika bi-annahum qaloolaysa AAalayna fee al-ommiyyeena sabeelun wayaqooloonaAAala Allahi alkathiba wahum yaAAlamoon","juz":3,"page":59},{"s":3,"a":76,"key":"3:76","ar":"بَلَىٰ مَنْ أَوْفَىٰ بِعَهْدِهِۦ وَٱتَّقَىٰ فَإِنَّ ٱللَّهَ يُحِبُّ ٱلْمُتَّقِينَ","en":"But yes, whoever fulfills his commitment and fears Allāh - then indeed, Allāh loves those who fear Him.","tr":"Bala man awfa biAAahdihi wattaqafa-inna Allaha yuhibbu almuttaqeen","juz":3,"page":59},{"s":3,"a":77,"key":"3:77","ar":"إِنَّ ٱلَّذِينَ يَشْتَرُونَ بِعَهْدِ ٱللَّهِ وَأَيْمَـٰنِهِمْ ثَمَنًا قَلِيلًا أُو۟لَـٰٓئِكَ لَا خَلَـٰقَ لَهُمْ فِى ٱلْـَٔاخِرَةِ وَلَا يُكَلِّمُهُمُ ٱللَّهُ وَلَا يَنظُرُ إِلَيْهِمْ يَوْمَ ٱلْقِيَـٰمَةِ وَلَا يُزَكِّيهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"Indeed, those who exchange the covenant of Allāh and their [own] oaths for a small price will have no share in the Hereafter, and Allāh will not speak to them or look at them on the Day of Resurrection, nor will He purify them; and they will have a painful punishment.","tr":"Inna allatheena yashtaroona biAAahdiAllahi waaymanihim thamanan qaleelan ola-ikala khalaqa lahum fee al-akhirati walayukallimuhumu Allahu wala yanthuruilayhim yawma alqiyamati wala yuzakkeehim walahumAAathabun aleem","juz":3,"page":59},{"s":3,"a":78,"key":"3:78","ar":"وَإِنَّ مِنْهُمْ لَفَرِيقًا يَلْوُۥنَ أَلْسِنَتَهُم بِٱلْكِتَـٰبِ لِتَحْسَبُوهُ مِنَ ٱلْكِتَـٰبِ وَمَا هُوَ مِنَ ٱلْكِتَـٰبِ وَيَقُولُونَ هُوَ مِنْ عِندِ ٱللَّهِ وَمَا هُوَ مِنْ عِندِ ٱللَّهِ وَيَقُولُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ وَهُمْ يَعْلَمُونَ","en":"And indeed, there is among them a party who alter the Scripture with their tongues so you may think it is from the Scripture, but it is not from the Scripture. And they say, \"This is from Allāh,\" but it is not from Allāh. And they speak untruth about Allāh while they know.","tr":"Wa-inna minhum lafareeqan yalwoonaalsinatahum bilkitabi litahsaboohu minaalkitabi wama huwa mina alkitabiwayaqooloona huwa min AAindi Allahi wama huwa minAAindi Allahi wayaqooloona AAala Allahi alkathibawahum yaAAlamoon","juz":3,"page":60},{"s":3,"a":79,"key":"3:79","ar":"مَا كَانَ لِبَشَرٍ أَن يُؤْتِيَهُ ٱللَّهُ ٱلْكِتَـٰبَ وَٱلْحُكْمَ وَٱلنُّبُوَّةَ ثُمَّ يَقُولَ لِلنَّاسِ كُونُوا۟ عِبَادًا لِّى مِن دُونِ ٱللَّهِ وَلَـٰكِن كُونُوا۟ رَبَّـٰنِيِّـۧنَ بِمَا كُنتُمْ تُعَلِّمُونَ ٱلْكِتَـٰبَ وَبِمَا كُنتُمْ تَدْرُسُونَ","en":"It is not for a human [prophet]1 that Allāh should give him the Scripture2 and authority and prophethood and then he would say to the people, \"Be servants to me rather than Allāh,\" but [instead, he would say], \"Be pious scholars of the Lord because of what you have taught of the Scripture and because of what you have studied.\"","tr":"Ma kana libasharin anyu/tiyahu Allahu alkitaba walhukmawannubuwwata thumma yaqoola linnasikoonoo AAibadan lee min dooni Allahi walakinkoonoo rabbaniyyeena bima kuntum tuAAallimoonaalkitaba wabima kuntum tadrusoon","juz":3,"page":60},{"s":3,"a":80,"key":"3:80","ar":"وَلَا يَأْمُرَكُمْ أَن تَتَّخِذُوا۟ ٱلْمَلَـٰٓئِكَةَ وَٱلنَّبِيِّـۧنَ أَرْبَابًا ۗ أَيَأْمُرُكُم بِٱلْكُفْرِ بَعْدَ إِذْ أَنتُم مُّسْلِمُونَ","en":"Nor could he order you to take the angels and prophets as lords. Would he order you to disbelief after you had been Muslims?","tr":"Wala ya/murakum an tattakhithooalmala-ikata wannabiyyeena arbabanaya/murukum bilkufri baAAda ith antum muslimoon","juz":3,"page":60},{"s":3,"a":81,"key":"3:81","ar":"وَإِذْ أَخَذَ ٱللَّهُ مِيثَـٰقَ ٱلنَّبِيِّـۧنَ لَمَآ ءَاتَيْتُكُم مِّن كِتَـٰبٍ وَحِكْمَةٍ ثُمَّ جَآءَكُمْ رَسُولٌ مُّصَدِّقٌ لِّمَا مَعَكُمْ لَتُؤْمِنُنَّ بِهِۦ وَلَتَنصُرُنَّهُۥ ۚ قَالَ ءَأَقْرَرْتُمْ وَأَخَذْتُمْ عَلَىٰ ذَٰلِكُمْ إِصْرِى ۖ قَالُوٓا۟ أَقْرَرْنَا ۚ قَالَ فَٱشْهَدُوا۟ وَأَنَا۠ مَعَكُم مِّنَ ٱلشَّـٰهِدِينَ","en":"And [recall, O People of the Scripture], when Allāh took the covenant of the prophets, [saying], \"Whatever I give you of the Scripture and wisdom and then there comes to you a messenger confirming what is with you, you [must] believe in him and support him.\" [Allāh] said, \"Have you acknowledged and taken upon that My commitment?\"1 They said, \"We have acknowledged it.\" He said, \"Then bear witness, and I am with you among the witnesses.\"","tr":"Wa-ith akhatha Allahumeethaqa annabiyyeena lama ataytukummin kitabin wahikmatin thumma jaakumrasoolun musaddiqun lima maAAakum latu/minunna bihiwalatansurunnahu qala aaqrartum waakhathtumAAala thalikum isree qaloo aqrarnaqala fashhadoo waana maAAakum mina ashshahideen","juz":3,"page":60},{"s":3,"a":82,"key":"3:82","ar":"فَمَن تَوَلَّىٰ بَعْدَ ذَٰلِكَ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ","en":"And whoever turned away after that - they were the defiantly disobedient.","tr":"Faman tawalla baAAda thalikafaola-ika humu alfasiqoon","juz":3,"page":60},{"s":3,"a":83,"key":"3:83","ar":"أَفَغَيْرَ دِينِ ٱللَّهِ يَبْغُونَ وَلَهُۥٓ أَسْلَمَ مَن فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ طَوْعًا وَكَرْهًا وَإِلَيْهِ يُرْجَعُونَ","en":"So is it other than the religion of Allāh they desire, while to Him have submitted [all] those within the heavens and earth, willingly or by compulsion, and to Him they will be returned?","tr":"Afaghayra deeni Allahi yabghoonawalahu aslama man fee assamawati wal-arditawAAan wakarhan wa-ilayhi yurjaAAoon","juz":3,"page":60},{"s":3,"a":84,"key":"3:84","ar":"قُلْ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ عَلَيْنَا وَمَآ أُنزِلَ عَلَىٰٓ إِبْرَٰهِيمَ وَإِسْمَـٰعِيلَ وَإِسْحَـٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطِ وَمَآ أُوتِىَ مُوسَىٰ وَعِيسَىٰ وَٱلنَّبِيُّونَ مِن رَّبِّهِمْ لَا نُفَرِّقُ بَيْنَ أَحَدٍ مِّنْهُمْ وَنَحْنُ لَهُۥ مُسْلِمُونَ","en":"Say, \"We have believed in Allāh and in what was revealed to us and what was revealed to Abraham, Ishmael, Isaac, Jacob, and the Descendants [al-Asbāṭ], and in what was given to Moses and Jesus and to the prophets from their Lord. We make no distinction between any of them, and we are Muslims [submitting] to Him.\"","tr":"Qul amanna billahiwama onzila AAalayna wama onzila AAalaibraheema wa-ismaAAeela wa-ishaqawayaAAqooba wal-asbati wama ootiya moosawaAAeesa wannabiyyoona min rabbihim lanufarriqu bayna ahadin minhum wanahnu lahumuslimoon","juz":3,"page":61},{"s":3,"a":85,"key":"3:85","ar":"وَمَن يَبْتَغِ غَيْرَ ٱلْإِسْلَـٰمِ دِينًا فَلَن يُقْبَلَ مِنْهُ وَهُوَ فِى ٱلْـَٔاخِرَةِ مِنَ ٱلْخَـٰسِرِينَ","en":"And whoever desires other than Islām as religion - never will it be accepted from him, and he, in the Hereafter, will be among the losers.","tr":"Waman yabtaghi ghayra al-islamideenan falan yuqbala minhu wahuwa fee al-akhirati minaalkhasireen","juz":3,"page":61},{"s":3,"a":86,"key":"3:86","ar":"كَيْفَ يَهْدِى ٱللَّهُ قَوْمًا كَفَرُوا۟ بَعْدَ إِيمَـٰنِهِمْ وَشَهِدُوٓا۟ أَنَّ ٱلرَّسُولَ حَقٌّ وَجَآءَهُمُ ٱلْبَيِّنَـٰتُ ۚ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"How shall Allāh guide a people who disbelieved after their belief and had witnessed that the Messenger is true and clear signs had come to them? And Allāh does not guide the wrongdoing people.","tr":"Kayfa yahdee Allahu qawman kafaroobaAAda eemanihim washahidoo anna arrasoola haqqunwajaahumu albayyinatu wallahu layahdee alqawma aththalimeen","juz":3,"page":61},{"s":3,"a":87,"key":"3:87","ar":"أُو۟لَـٰٓئِكَ جَزَآؤُهُمْ أَنَّ عَلَيْهِمْ لَعْنَةَ ٱللَّهِ وَٱلْمَلَـٰٓئِكَةِ وَٱلنَّاسِ أَجْمَعِينَ","en":"Those - their recompense will be that upon them is the curse of Allāh and the angels and the people, all together,","tr":"Ola-ika jazaohum annaAAalayhim laAAnata Allahi walmala-ikati wannasiajmaAAeen","juz":3,"page":61},{"s":3,"a":88,"key":"3:88","ar":"خَـٰلِدِينَ فِيهَا لَا يُخَفَّفُ عَنْهُمُ ٱلْعَذَابُ وَلَا هُمْ يُنظَرُونَ","en":"Abiding eternally therein. The punishment will not be lightened for them, nor will they be reprieved,","tr":"Khalideena feeha layukhaffafu AAanhumu alAAathabu wala hum yuntharoon","juz":3,"page":61},{"s":3,"a":89,"key":"3:89","ar":"إِلَّا ٱلَّذِينَ تَابُوا۟ مِنۢ بَعْدِ ذَٰلِكَ وَأَصْلَحُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"Except for those who repent after that1 and correct themselves. For indeed, Allāh is Forgiving and Merciful.","tr":"Illa allatheena taboomin baAAdi thalika waaslahoo fa-inna Allahaghafoorun raheem","juz":3,"page":61},{"s":3,"a":90,"key":"3:90","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ بَعْدَ إِيمَـٰنِهِمْ ثُمَّ ٱزْدَادُوا۟ كُفْرًا لَّن تُقْبَلَ تَوْبَتُهُمْ وَأُو۟لَـٰٓئِكَ هُمُ ٱلضَّآلُّونَ","en":"Indeed, those who disbelieve [i.e., reject the message] after their belief and then increase in disbelief - never will their [claimed] repentance be accepted, and they are the ones astray.","tr":"Inna allatheena kafaroo baAAda eemanihimthumma izdadoo kufran lan tuqbala tawbatuhum waola-ikahumu addalloon","juz":3,"page":61},{"s":3,"a":91,"key":"3:91","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَمَاتُوا۟ وَهُمْ كُفَّارٌ فَلَن يُقْبَلَ مِنْ أَحَدِهِم مِّلْءُ ٱلْأَرْضِ ذَهَبًا وَلَوِ ٱفْتَدَىٰ بِهِۦٓ ۗ أُو۟لَـٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌ وَمَا لَهُم مِّن نَّـٰصِرِينَ","en":"Indeed, those who disbelieve and die while they are disbelievers - never would the [whole] capacity of the earth in gold be accepted from one of them if he would [seek to] ransom himself with it. For those there will be a painful punishment, and they will have no helpers.","tr":"Inna allatheena kafaroo wamatoowahum kuffarun falan yuqbala min ahadihim miloal-ardi thahaban walawi iftada bihi ola-ikalahum AAathabun aleemun wama lahum min nasireen","juz":3,"page":61},{"s":3,"a":92,"key":"3:92","ar":"لَن تَنَالُوا۟ ٱلْبِرَّ حَتَّىٰ تُنفِقُوا۟ مِمَّا تُحِبُّونَ ۚ وَمَا تُنفِقُوا۟ مِن شَىْءٍ فَإِنَّ ٱللَّهَ بِهِۦ عَلِيمٌ","en":"Never will you attain the good [reward]1 until you spend [in the way of Allāh] from that which you love. And whatever you spend - indeed, Allāh is Knowing of it.","tr":"Lan tanaloo albirra hattatunfiqoo mimma tuhibboona wama tunfiqoo minshay-in fa-inna Allaha bihi AAaleem","juz":3,"page":62},{"s":3,"a":93,"key":"3:93","ar":"۞ كُلُّ ٱلطَّعَامِ كَانَ حِلًّا لِّبَنِىٓ إِسْرَٰٓءِيلَ إِلَّا مَا حَرَّمَ إِسْرَٰٓءِيلُ عَلَىٰ نَفْسِهِۦ مِن قَبْلِ أَن تُنَزَّلَ ٱلتَّوْرَىٰةُ ۗ قُلْ فَأْتُوا۟ بِٱلتَّوْرَىٰةِ فَٱتْلُوهَآ إِن كُنتُمْ صَـٰدِقِينَ","en":"All food was lawful to the Children of Israel except what Israel [i.e., Jacob] had made unlawful to himself before the Torah was revealed. Say, [O Muḥammad], \"So bring the Torah and recite it, if you should be truthful.\"","tr":"Kullu attaAAami kanahillan libanee isra-eela illa ma harramaisra-eelu AAala nafsihi min qabli an tunazzala attawratuqul fa/too bittawrati fatlooha inkuntum sadiqeen","juz":4,"page":62},{"s":3,"a":94,"key":"3:94","ar":"فَمَنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ ٱلْكَذِبَ مِنۢ بَعْدِ ذَٰلِكَ فَأُو۟لَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ","en":"And whoever invents about Allāh untruth after that - then those are [truly] the wrongdoers.","tr":"Famani iftara AAala Allahialkathiba min baAAdi thalika faola-ika humuathalimoon","juz":4,"page":62},{"s":3,"a":95,"key":"3:95","ar":"قُلْ صَدَقَ ٱللَّهُ ۗ فَٱتَّبِعُوا۟ مِلَّةَ إِبْرَٰهِيمَ حَنِيفًا وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ","en":"Say, \"Allāh has told the truth. So follow the religion of Abraham, inclining toward truth; and he was not of the polytheists.\"1","tr":"Qul sadaqa Allahu fattabiAAoomillata ibraheema haneefan wama kanamina almushrikeen","juz":4,"page":62},{"s":3,"a":96,"key":"3:96","ar":"إِنَّ أَوَّلَ بَيْتٍ وُضِعَ لِلنَّاسِ لَلَّذِى بِبَكَّةَ مُبَارَكًا وَهُدًى لِّلْعَـٰلَمِينَ","en":"Indeed, the first House [of worship] established for mankind was that at Bakkah [i.e., Makkah] - blessed and a guidance for the worlds.","tr":"Inna awwala baytin wudiAAa linnasilallathee bibakkata mubarakan wahudan lilAAalameen","juz":4,"page":62},{"s":3,"a":97,"key":"3:97","ar":"فِيهِ ءَايَـٰتٌۢ بَيِّنَـٰتٌ مَّقَامُ إِبْرَٰهِيمَ ۖ وَمَن دَخَلَهُۥ كَانَ ءَامِنًا ۗ وَلِلَّهِ عَلَى ٱلنَّاسِ حِجُّ ٱلْبَيْتِ مَنِ ٱسْتَطَاعَ إِلَيْهِ سَبِيلًا ۚ وَمَن كَفَرَ فَإِنَّ ٱللَّهَ غَنِىٌّ عَنِ ٱلْعَـٰلَمِينَ","en":"In it are clear signs [such as] the standing place of Abraham. And whoever enters it [i.e., the Ḥaram] shall be safe. And [due] to Allāh from the people is a pilgrimage to the House - for whoever is able to find thereto a way. But whoever disbelieves [i.e., refuses] - then indeed, Allāh is free from need of the worlds.1","tr":"Feehi ayatun bayyinatunmaqamu ibraheema waman dakhalahu kana aminanwalillahi AAala annasi hijjualbayti mani istataAAa ilayhi sabeelan waman kafarafa-inna Allaha ghaniyyun AAani alAAalameen","juz":4,"page":62},{"s":3,"a":98,"key":"3:98","ar":"قُلْ يَـٰٓأَهْلَ ٱلْكِتَـٰبِ لِمَ تَكْفُرُونَ بِـَٔايَـٰتِ ٱللَّهِ وَٱللَّهُ شَهِيدٌ عَلَىٰ مَا تَعْمَلُونَ","en":"Say, \"O People of the Scripture, why do you disbelieve in the verses of Allāh while Allāh is Witness over what you do?\"","tr":"Qul ya ahla alkitabi limatakfuroona bi-ayati Allahi wallahushaheedun AAala ma taAAmaloon","juz":4,"page":62},{"s":3,"a":99,"key":"3:99","ar":"قُلْ يَـٰٓأَهْلَ ٱلْكِتَـٰبِ لِمَ تَصُدُّونَ عَن سَبِيلِ ٱللَّهِ مَنْ ءَامَنَ تَبْغُونَهَا عِوَجًا وَأَنتُمْ شُهَدَآءُ ۗ وَمَا ٱللَّهُ بِغَـٰفِلٍ عَمَّا تَعْمَلُونَ","en":"Say, \"O People of the Scripture, why do you avert from the way of Allāh those who believe, seeking to make it [seem] deviant, while you are witnesses [to the truth]? And Allāh is not unaware of what you do.\"","tr":"Qul ya ahla alkitabi lima tasuddoonaAAan sabeeli Allahi man amana tabghoonahaAAiwajan waantum shuhadao wama Allahu bighafilinAAamma taAAmaloon","juz":4,"page":62},{"s":3,"a":100,"key":"3:100","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ فَرِيقًا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ يَرُدُّوكُم بَعْدَ إِيمَـٰنِكُمْ كَـٰفِرِينَ","en":"O you who have believed, if you obey a party of those who were given the Scripture, they would turn you back, after your belief, [to being] unbelievers.","tr":"Ya ayyuha allatheena amanooin tuteeAAoo fareeqan mina allatheena ootoo alkitabayaruddookum baAAda eemanikum kafireen","juz":4,"page":62},{"s":3,"a":101,"key":"3:101","ar":"وَكَيْفَ تَكْفُرُونَ وَأَنتُمْ تُتْلَىٰ عَلَيْكُمْ ءَايَـٰتُ ٱللَّهِ وَفِيكُمْ رَسُولُهُۥ ۗ وَمَن يَعْتَصِم بِٱللَّهِ فَقَدْ هُدِىَ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"And how could you disbelieve while to you are being recited the verses of Allāh and among you is His Messenger? And whoever holds firmly to Allāh1 has [indeed] been guided to a straight path.","tr":"Wakayfa takfuroona waantum tutlaAAalaykum ayatu Allahi wafeekum rasooluhuwaman yaAAtasim billahi faqad hudiya ilasiratin mustaqeem","juz":4,"page":63},{"s":3,"a":102,"key":"3:102","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ حَقَّ تُقَاتِهِۦ وَلَا تَمُوتُنَّ إِلَّا وَأَنتُم مُّسْلِمُونَ","en":"O you who have believed, fear Allāh as He should be feared and do not die except as Muslims [in submission to Him].","tr":"Ya ayyuha allatheena amanooittaqoo Allaha haqqa tuqatihi walatamootunna illa waantum muslimoon","juz":4,"page":63},{"s":3,"a":103,"key":"3:103","ar":"وَٱعْتَصِمُوا۟ بِحَبْلِ ٱللَّهِ جَمِيعًا وَلَا تَفَرَّقُوا۟ ۚ وَٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ إِذْ كُنتُمْ أَعْدَآءً فَأَلَّفَ بَيْنَ قُلُوبِكُمْ فَأَصْبَحْتُم بِنِعْمَتِهِۦٓ إِخْوَٰنًا وَكُنتُمْ عَلَىٰ شَفَا حُفْرَةٍ مِّنَ ٱلنَّارِ فَأَنقَذَكُم مِّنْهَا ۗ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَـٰتِهِۦ لَعَلَّكُمْ تَهْتَدُونَ","en":"And hold firmly to the rope1 of Allāh all together and do not become divided. And remember the favor of Allāh upon you - when you were enemies and He brought your hearts together and you became, by His favor, brothers. And you were on the edge of a pit of the Fire, and He saved you from it. Thus does Allāh make clear to you His verses that you may be guided.","tr":"WaAAtasimoo bihabliAllahi jameeAAan wala tafarraqoo wathkurooniAAmata Allahi AAalaykum ith kuntum aAAdaanfaallafa bayna quloobikum faasbahtum biniAAmatihiikhwanan wakuntum AAala shafa hufratinmina annari faanqathakum minha kathalikayubayyinu Allahu lakum ayatihi laAAallakumtahtadoon","juz":4,"page":63},{"s":3,"a":104,"key":"3:104","ar":"وَلْتَكُن مِّنكُمْ أُمَّةٌ يَدْعُونَ إِلَى ٱلْخَيْرِ وَيَأْمُرُونَ بِٱلْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ٱلْمُنكَرِ ۚ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"And let there be [arising] from you a nation inviting to [all that is] good, enjoining what is right and forbidding what is wrong,1 and those will be the successful.","tr":"Waltakun minkum ommatun yadAAoona ilaalkhayri waya/muroona bilmaAAroofi wayanhawna AAanialmunkari waola-ika humu almuflihoon","juz":4,"page":63},{"s":3,"a":105,"key":"3:105","ar":"وَلَا تَكُونُوا۟ كَٱلَّذِينَ تَفَرَّقُوا۟ وَٱخْتَلَفُوا۟ مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْبَيِّنَـٰتُ ۚ وَأُو۟لَـٰٓئِكَ لَهُمْ عَذَابٌ عَظِيمٌ","en":"And do not be like the ones who became divided and differed after the clear proofs had come to them. And those will have a great punishment","tr":"Wala takoonoo kallatheenatafarraqoo wakhtalafoo min baAAdi ma jaahumualbayyinatu waola-ika lahum AAathabun AAatheem","juz":4,"page":63},{"s":3,"a":106,"key":"3:106","ar":"يَوْمَ تَبْيَضُّ وُجُوهٌ وَتَسْوَدُّ وُجُوهٌ ۚ فَأَمَّا ٱلَّذِينَ ٱسْوَدَّتْ وُجُوهُهُمْ أَكَفَرْتُم بَعْدَ إِيمَـٰنِكُمْ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْفُرُونَ","en":"On the Day [some] faces will turn white and [some] faces will turn black. As for those whose faces turn black, [to them it will be said], \"Did you disbelieve [i.e., reject faith] after your belief? Then taste the punishment for what you used to reject.\"","tr":"Yawma tabyaddu wujoohun wataswadduwujoohun faamma allatheena iswaddat wujoohuhumakafartum baAAda eemanikum fathooqoo alAAathababima kuntum takfuroon","juz":4,"page":63},{"s":3,"a":107,"key":"3:107","ar":"وَأَمَّا ٱلَّذِينَ ٱبْيَضَّتْ وُجُوهُهُمْ فَفِى رَحْمَةِ ٱللَّهِ هُمْ فِيهَا خَـٰلِدُونَ","en":"But as for those whose faces turn white, [they will be] within the mercy of Allāh. They will abide therein eternally.","tr":"Waamma allatheena ibyaddatwujoohuhum fafee rahmati Allahi hum feeha khalidoon","juz":4,"page":63},{"s":3,"a":108,"key":"3:108","ar":"تِلْكَ ءَايَـٰتُ ٱللَّهِ نَتْلُوهَا عَلَيْكَ بِٱلْحَقِّ ۗ وَمَا ٱللَّهُ يُرِيدُ ظُلْمًا لِّلْعَـٰلَمِينَ","en":"These are the verses of Allāh. We recite them to you, [O Muḥammad], in truth; and Allāh wants no injustice to the worlds [i.e., His creatures].","tr":"Tilka ayatu Allahinatlooha AAalayka bilhaqqi wama Allahuyureedu thulman lilAAalameen","juz":4,"page":63},{"s":3,"a":109,"key":"3:109","ar":"وَلِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ","en":"To Allāh belongs whatever is in the heavens and whatever is on the earth. And to Allāh will [all] matters be returned.","tr":"Walillahi ma fee assamawatiwama fee al-ardi wa-ila AllahiturjaAAu al-omoor","juz":4,"page":64},{"s":3,"a":110,"key":"3:110","ar":"كُنتُمْ خَيْرَ أُمَّةٍ أُخْرِجَتْ لِلنَّاسِ تَأْمُرُونَ بِٱلْمَعْرُوفِ وَتَنْهَوْنَ عَنِ ٱلْمُنكَرِ وَتُؤْمِنُونَ بِٱللَّهِ ۗ وَلَوْ ءَامَنَ أَهْلُ ٱلْكِتَـٰبِ لَكَانَ خَيْرًا لَّهُم ۚ مِّنْهُمُ ٱلْمُؤْمِنُونَ وَأَكْثَرُهُمُ ٱلْفَـٰسِقُونَ","en":"You are the best nation produced [as an example] for mankind. You enjoin what is right and forbid what is wrong and believe in Allāh. If only the People of the Scripture had believed, it would have been better for them. Among them are believers, but most of them are defiantly disobedient.","tr":"Kuntum khayra ommatin okhrijat linnasita/muroona bilmaAAroofi watanhawna AAani almunkariwatu/minoona billahi walaw amana ahlu alkitabilakana khayran lahum minhumu almu/minoona waaktharuhumualfasiqoon","juz":4,"page":64},{"s":3,"a":111,"key":"3:111","ar":"لَن يَضُرُّوكُمْ إِلَّآ أَذًى ۖ وَإِن يُقَـٰتِلُوكُمْ يُوَلُّوكُمُ ٱلْأَدْبَارَ ثُمَّ لَا يُنصَرُونَ","en":"They will not harm you except for [some] annoyance. And if they fight you, they will show you their backs [i.e., retreat]; then they will not be aided.","tr":"Lan yadurrookum illa athanwa-in yuqatilookum yuwallookumu al-adbara thumma layunsaroon","juz":4,"page":64},{"s":3,"a":112,"key":"3:112","ar":"ضُرِبَتْ عَلَيْهِمُ ٱلذِّلَّةُ أَيْنَ مَا ثُقِفُوٓا۟ إِلَّا بِحَبْلٍ مِّنَ ٱللَّهِ وَحَبْلٍ مِّنَ ٱلنَّاسِ وَبَآءُو بِغَضَبٍ مِّنَ ٱللَّهِ وَضُرِبَتْ عَلَيْهِمُ ٱلْمَسْكَنَةُ ۚ ذَٰلِكَ بِأَنَّهُمْ كَانُوا۟ يَكْفُرُونَ بِـَٔايَـٰتِ ٱللَّهِ وَيَقْتُلُونَ ٱلْأَنۢبِيَآءَ بِغَيْرِ حَقٍّ ۚ ذَٰلِكَ بِمَا عَصَوا۟ وَّكَانُوا۟ يَعْتَدُونَ","en":"They have been put under humiliation [by Allāh] wherever they are overtaken, except for a rope [i.e., covenant] from Allāh and a rope [i.e., treaty] from the people [i.e., the Muslims].1 And they have drawn upon themselves anger from Allāh and have been put under destitution. That is because they disbelieved in [i.e., rejected] the verses of Allāh and killed the prophets without right. That is because they disobeyed and [habitually] transgressed.","tr":"Duribat AAalayhimu aththillatuayna ma thuqifoo illa bihablin mina Allahiwahablin mina annasi wabaoo bighadabinmina Allahi waduribat AAalayhimu almaskanatu thalikabi-annahum kanoo yakfuroona bi-ayati Allahiwayaqtuloona al-anbiyaa bighayri haqqin thalikabima AAasaw wakanoo yaAAtadoon","juz":4,"page":64},{"s":3,"a":113,"key":"3:113","ar":"۞ لَيْسُوا۟ سَوَآءً ۗ مِّنْ أَهْلِ ٱلْكِتَـٰبِ أُمَّةٌ قَآئِمَةٌ يَتْلُونَ ءَايَـٰتِ ٱللَّهِ ءَانَآءَ ٱلَّيْلِ وَهُمْ يَسْجُدُونَ","en":"They are not [all] the same; among the People of the Scripture is a community1 standing [in obedience], reciting the verses of Allāh during periods of the night and prostrating [in prayer].","tr":"Laysoo sawaan min ahli alkitabiommatun qa-imatun yatloona ayati Allahianaa allayli wahum yasjudoon","juz":4,"page":64},{"s":3,"a":114,"key":"3:114","ar":"يُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ وَيَأْمُرُونَ بِٱلْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ٱلْمُنكَرِ وَيُسَـٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَأُو۟لَـٰٓئِكَ مِنَ ٱلصَّـٰلِحِينَ","en":"They believe in Allāh and the Last Day, and they enjoin what is right and forbid what is wrong and hasten to good deeds. And those are among the righteous.","tr":"Yu/minoona billahi walyawmial-akhiri waya/muroona bilmaAAroofi wayanhawnaAAani almunkari wayusariAAoona fee alkhayrati waola-ikamina assaliheen","juz":4,"page":64},{"s":3,"a":115,"key":"3:115","ar":"وَمَا يَفْعَلُوا۟ مِنْ خَيْرٍ فَلَن يُكْفَرُوهُ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلْمُتَّقِينَ","en":"And whatever good they do - never will it be denied them. And Allāh is Knowing of the righteous.","tr":"Wama yafAAaloo min khayrin falanyukfaroohu wallahu AAaleemun bilmuttaqeen","juz":4,"page":64},{"s":3,"a":116,"key":"3:116","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ لَن تُغْنِىَ عَنْهُمْ أَمْوَٰلُهُمْ وَلَآ أَوْلَـٰدُهُم مِّنَ ٱللَّهِ شَيْـًٔا ۖ وَأُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۚ هُمْ فِيهَا خَـٰلِدُونَ","en":"Indeed, those who disbelieve - never will their wealth or their children avail them against Allāh at all, and those are the companions of the Fire; they will abide therein eternally.","tr":"Inna allatheena kafaroo lan tughniyaAAanhum amwaluhum wala awladuhum mina Allahishay-an waola-ika as-habu annarihum feeha khalidoon","juz":4,"page":65},{"s":3,"a":117,"key":"3:117","ar":"مَثَلُ مَا يُنفِقُونَ فِى هَـٰذِهِ ٱلْحَيَوٰةِ ٱلدُّنْيَا كَمَثَلِ رِيحٍ فِيهَا صِرٌّ أَصَابَتْ حَرْثَ قَوْمٍ ظَلَمُوٓا۟ أَنفُسَهُمْ فَأَهْلَكَتْهُ ۚ وَمَا ظَلَمَهُمُ ٱللَّهُ وَلَـٰكِنْ أَنفُسَهُمْ يَظْلِمُونَ","en":"The example of what they spend in this worldly life is like that of a wind containing frost which strikes the harvest of a people who have wronged themselves [i.e., sinned] and destroys it. And Allāh has not wronged them, but they wrong themselves.","tr":"Mathalu ma yunfiqoona fee hathihialhayati addunya kamathali reehinfeeha sirrun asabat hartha qawmin thalamooanfusahum faahlakat-hu wama thalamahumu Allahuwalakin anfusahum yathlimoon","juz":4,"page":65},{"s":3,"a":118,"key":"3:118","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ بِطَانَةً مِّن دُونِكُمْ لَا يَأْلُونَكُمْ خَبَالًا وَدُّوا۟ مَا عَنِتُّمْ قَدْ بَدَتِ ٱلْبَغْضَآءُ مِنْ أَفْوَٰهِهِمْ وَمَا تُخْفِى صُدُورُهُمْ أَكْبَرُ ۚ قَدْ بَيَّنَّا لَكُمُ ٱلْـَٔايَـٰتِ ۖ إِن كُنتُمْ تَعْقِلُونَ","en":"O you who have believed, do not take as intimates those other than yourselves [i.e., believers], for they will not spare you [any] ruin. They wish you would have hardship. Hatred has already appeared from their mouths, and what their breasts conceal is greater. We have certainly made clear to you the signs, if you will use reason.","tr":"Ya ayyuha allatheena amanoola tattakhithoo bitanatan min doonikum laya/loonakum khabalan waddoo ma AAanittum qad badatialbaghdao min afwahihim wama tukhfee sudooruhumakbaru qad bayyanna lakumu al-ayati inkuntum taAAqiloon","juz":4,"page":65},{"s":3,"a":119,"key":"3:119","ar":"هَـٰٓأَنتُمْ أُو۟لَآءِ تُحِبُّونَهُمْ وَلَا يُحِبُّونَكُمْ وَتُؤْمِنُونَ بِٱلْكِتَـٰبِ كُلِّهِۦ وَإِذَا لَقُوكُمْ قَالُوٓا۟ ءَامَنَّا وَإِذَا خَلَوْا۟ عَضُّوا۟ عَلَيْكُمُ ٱلْأَنَامِلَ مِنَ ٱلْغَيْظِ ۚ قُلْ مُوتُوا۟ بِغَيْظِكُمْ ۗ إِنَّ ٱللَّهَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"Here you are loving them but they are not loving you, while you believe in the Scripture - all of it.1 And when they meet you, they say, \"We believe.\" But when they are alone, they bite their fingertips at you in rage. Say, \"Die in your rage. Indeed, Allāh is Knowing of that within the breasts.\"","tr":"Ha antum ola-i tuhibboonahumwala yuhibboonakum watu/minoona bilkitabikullihi wa-itha laqookum qaloo amannawa-itha khalaw AAaddoo AAalaykumu al-anamilamina alghaythi qul mootoo bighaythikuminna Allaha AAaleemun bithati assudoor","juz":4,"page":65},{"s":3,"a":120,"key":"3:120","ar":"إِن تَمْسَسْكُمْ حَسَنَةٌ تَسُؤْهُمْ وَإِن تُصِبْكُمْ سَيِّئَةٌ يَفْرَحُوا۟ بِهَا ۖ وَإِن تَصْبِرُوا۟ وَتَتَّقُوا۟ لَا يَضُرُّكُمْ كَيْدُهُمْ شَيْـًٔا ۗ إِنَّ ٱللَّهَ بِمَا يَعْمَلُونَ مُحِيطٌ","en":"If good touches you, it distresses them; but if harm strikes you, they rejoice at it. And if you are patient and fear Allāh, their plot will not harm you at all. Indeed, Allāh is encompassing of what they do.","tr":"In tamsaskum hasanatun tasu/humwa-in tusibkum sayyi-atun yafrahoo bihawa-in tasbiroo watattaqoo la yadurrukumkayduhum shay-an inna Allaha bima yaAAmaloona muheet","juz":4,"page":65},{"s":3,"a":121,"key":"3:121","ar":"وَإِذْ غَدَوْتَ مِنْ أَهْلِكَ تُبَوِّئُ ٱلْمُؤْمِنِينَ مَقَـٰعِدَ لِلْقِتَالِ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ","en":"And [remember] when you, [O Muḥammad], left your family in the morning to post the believers at their stations for the battle [of Uḥud] - and Allāh is Hearing and Knowing -","tr":"Wa-ith ghadawta min ahlika tubawwi-oalmu/mineena maqaAAida lilqitali wallahusameeAAun AAaleem","juz":4,"page":65},{"s":3,"a":122,"key":"3:122","ar":"إِذْ هَمَّت طَّآئِفَتَانِ مِنكُمْ أَن تَفْشَلَا وَٱللَّهُ وَلِيُّهُمَا ۗ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ","en":"When two parties among you were about to lose courage, but Allāh was their ally; and upon Allāh the believers should rely.","tr":"Ith hammat ta-ifataniminkum an tafshala wallahu waliyyuhumawaAAala Allahi falyatawakkali almu/minoon","juz":4,"page":66},{"s":3,"a":123,"key":"3:123","ar":"وَلَقَدْ نَصَرَكُمُ ٱللَّهُ بِبَدْرٍ وَأَنتُمْ أَذِلَّةٌ ۖ فَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تَشْكُرُونَ","en":"And already had Allāh given you victory at [the battle of] Badr while you were weak [i.e., few in number]. Then fear Allāh; perhaps you will be grateful.","tr":"Walaqad nasarakumu Allahubibadrin waantum athillatun fattaqoo AllahalaAAallakum tashkuroon","juz":4,"page":66},{"s":3,"a":124,"key":"3:124","ar":"إِذْ تَقُولُ لِلْمُؤْمِنِينَ أَلَن يَكْفِيَكُمْ أَن يُمِدَّكُمْ رَبُّكُم بِثَلَـٰثَةِ ءَالَـٰفٍ مِّنَ ٱلْمَلَـٰٓئِكَةِ مُنزَلِينَ","en":"[Remember] when you said to the believers, \"Is it not sufficient for you that your Lord should reinforce you with three thousand angels sent down?","tr":"Ith taqoolu lilmu/mineena alanyakfiyakum an yumiddakum rabbukum bithalathati alafinmina almala-ikati munzaleen","juz":4,"page":66},{"s":3,"a":125,"key":"3:125","ar":"بَلَىٰٓ ۚ إِن تَصْبِرُوا۟ وَتَتَّقُوا۟ وَيَأْتُوكُم مِّن فَوْرِهِمْ هَـٰذَا يُمْدِدْكُمْ رَبُّكُم بِخَمْسَةِ ءَالَـٰفٍ مِّنَ ٱلْمَلَـٰٓئِكَةِ مُسَوِّمِينَ","en":"Yes, if you remain patient and conscious of Allāh and they [i.e., the enemy] come upon you [attacking] in rage, your Lord will reinforce you with five thousand angels having marks [of distinction].\"","tr":"Bala in tasbiroo watattaqoowaya/tookum min fawrihim hatha yumdidkum rabbukumbikhamsati alafin mina almala-ikatimusawwimeen","juz":4,"page":66},{"s":3,"a":126,"key":"3:126","ar":"وَمَا جَعَلَهُ ٱللَّهُ إِلَّا بُشْرَىٰ لَكُمْ وَلِتَطْمَئِنَّ قُلُوبُكُم بِهِۦ ۗ وَمَا ٱلنَّصْرُ إِلَّا مِنْ عِندِ ٱللَّهِ ٱلْعَزِيزِ ٱلْحَكِيمِ","en":"And Allāh made it not except as [a sign of] good tidings for you and to reassure your hearts thereby. And victory is not except from Allāh, the Exalted in Might, the Wise -","tr":"Wama jaAAalahu Allahu illabushra lakum walitatma-inna quloobukum bihi wamaannasru illa min AAindi AllahialAAazeezi alhakeem","juz":4,"page":66},{"s":3,"a":127,"key":"3:127","ar":"لِيَقْطَعَ طَرَفًا مِّنَ ٱلَّذِينَ كَفَرُوٓا۟ أَوْ يَكْبِتَهُمْ فَيَنقَلِبُوا۟ خَآئِبِينَ","en":"That He might cut down a section of the disbelievers or suppress them so that they turn back disappointed.","tr":"LiyaqtaAAa tarafan mina allatheenakafaroo aw yakbitahum fayanqaliboo kha-ibeen","juz":4,"page":66},{"s":3,"a":128,"key":"3:128","ar":"لَيْسَ لَكَ مِنَ ٱلْأَمْرِ شَىْءٌ أَوْ يَتُوبَ عَلَيْهِمْ أَوْ يُعَذِّبَهُمْ فَإِنَّهُمْ ظَـٰلِمُونَ","en":"Not for you, [O Muḥammad, but for Allāh], is the decision whether He should [cut them down] or forgive them or punish them, for indeed, they are wrongdoers.","tr":"Laysa laka mina al-amri shay-on aw yatoobaAAalayhim aw yuAAaththibahum fa-innahum thalimoon","juz":4,"page":66},{"s":3,"a":129,"key":"3:129","ar":"وَلِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ يَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"And to Allāh belongs whatever is in the heavens and whatever is on the earth. He forgives whom He wills and punishes whom He wills. And Allāh is Forgiving and Merciful.","tr":"Walillahi ma fee assamawatiwama fee al-ardi yaghfiru liman yashaowayuAAaththibu man yashao wallahughafoorun raheem","juz":4,"page":66},{"s":3,"a":130,"key":"3:130","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَأْكُلُوا۟ ٱلرِّبَوٰٓا۟ أَضْعَـٰفًا مُّضَـٰعَفَةً ۖ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُفْلِحُونَ","en":"O you who have believed, do not consume usury, doubled and multiplied, but fear Allāh that you may be successful.","tr":"Ya ayyuha allatheena amanoola ta/kuloo arriba adAAafanmudaAAafatan wattaqoo Allaha laAAallakumtuflihoon","juz":4,"page":66},{"s":3,"a":131,"key":"3:131","ar":"وَٱتَّقُوا۟ ٱلنَّارَ ٱلَّتِىٓ أُعِدَّتْ لِلْكَـٰفِرِينَ","en":"And fear the Fire, which has been prepared for the disbelievers.","tr":"Wattaqoo annaraallatee oAAiddat lilkafireen","juz":4,"page":66},{"s":3,"a":132,"key":"3:132","ar":"وَأَطِيعُوا۟ ٱللَّهَ وَٱلرَّسُولَ لَعَلَّكُمْ تُرْحَمُونَ","en":"And obey Allāh and the Messenger that you may obtain mercy.","tr":"WaateeAAoo Allaha warrasoolalaAAallakum turhamoon","juz":4,"page":66},{"s":3,"a":133,"key":"3:133","ar":"۞ وَسَارِعُوٓا۟ إِلَىٰ مَغْفِرَةٍ مِّن رَّبِّكُمْ وَجَنَّةٍ عَرْضُهَا ٱلسَّمَـٰوَٰتُ وَٱلْأَرْضُ أُعِدَّتْ لِلْمُتَّقِينَ","en":"And hasten to forgiveness from your Lord and a garden [i.e., Paradise] as wide as the heavens and earth, prepared for the righteous","tr":"WasariAAoo ila maghfiratinmin rabbikum wajannatin AAarduha assamawatuwal-ardu oAAiddat lilmuttaqeen","juz":4,"page":67},{"s":3,"a":134,"key":"3:134","ar":"ٱلَّذِينَ يُنفِقُونَ فِى ٱلسَّرَّآءِ وَٱلضَّرَّآءِ وَٱلْكَـٰظِمِينَ ٱلْغَيْظَ وَٱلْعَافِينَ عَنِ ٱلنَّاسِ ۗ وَٱللَّهُ يُحِبُّ ٱلْمُحْسِنِينَ","en":"Who spend [in the cause of Allāh] during ease and hardship and who restrain anger and who pardon the people - and Allāh loves the doers of good;","tr":"Allatheena yunfiqoona fee assarra-iwaddarra-i walkathimeenaalghaytha walAAafeena AAani annasiwallahu yuhibbu almuhsineen","juz":4,"page":67},{"s":3,"a":135,"key":"3:135","ar":"وَٱلَّذِينَ إِذَا فَعَلُوا۟ فَـٰحِشَةً أَوْ ظَلَمُوٓا۟ أَنفُسَهُمْ ذَكَرُوا۟ ٱللَّهَ فَٱسْتَغْفَرُوا۟ لِذُنُوبِهِمْ وَمَن يَغْفِرُ ٱلذُّنُوبَ إِلَّا ٱللَّهُ وَلَمْ يُصِرُّوا۟ عَلَىٰ مَا فَعَلُوا۟ وَهُمْ يَعْلَمُونَ","en":"And those who, when they commit an immorality or wrong themselves [by transgression], remember Allāh and seek forgiveness for their sins - and who can forgive sins except Allāh? - and [who] do not persist in what they have done while they know.","tr":"Wallatheena ithafaAAaloo fahishatan aw thalamoo anfusahum thakarooAllaha fastaghfaroo lithunoobihim wamanyaghfiru aththunooba illa Allahuwalam yusirroo AAala ma faAAaloo wahumyaAAlamoon","juz":4,"page":67},{"s":3,"a":136,"key":"3:136","ar":"أُو۟لَـٰٓئِكَ جَزَآؤُهُم مَّغْفِرَةٌ مِّن رَّبِّهِمْ وَجَنَّـٰتٌ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا ۚ وَنِعْمَ أَجْرُ ٱلْعَـٰمِلِينَ","en":"Those - their reward is forgiveness from their Lord and gardens beneath which rivers flow [in Paradise], wherein they will abide eternally; and excellent is the reward of the [righteous] workers.","tr":"Ola-ika jazaohum maghfiratunmin rabbihim wajannatun tajree min tahtihaal-anharu khalideena feeha waniAAma ajrualAAamileen","juz":4,"page":67},{"s":3,"a":137,"key":"3:137","ar":"قَدْ خَلَتْ مِن قَبْلِكُمْ سُنَنٌ فَسِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُكَذِّبِينَ","en":"Similar situations [as yours] have passed on before you, so proceed throughout the earth and observe how was the end of those who denied.","tr":"Qad khalat min qablikum sunanun faseeroofee al-ardi fanthuroo kayfa kanaAAaqibatu almukaththibeen","juz":4,"page":67},{"s":3,"a":138,"key":"3:138","ar":"هَـٰذَا بَيَانٌ لِّلنَّاسِ وَهُدًى وَمَوْعِظَةٌ لِّلْمُتَّقِينَ","en":"This [Qur’ān] is a clear statement to [all] the people and a guidance and instruction for those conscious of Allāh.","tr":"Hatha bayanun linnasiwahudan wamawAAithatun lilmuttaqeen","juz":4,"page":67},{"s":3,"a":139,"key":"3:139","ar":"وَلَا تَهِنُوا۟ وَلَا تَحْزَنُوا۟ وَأَنتُمُ ٱلْأَعْلَوْنَ إِن كُنتُم مُّؤْمِنِينَ","en":"So do not weaken and do not grieve, and you will be superior if you are [true] believers.","tr":"Wala tahinoo wala tahzanoowaantumu al-aAAlawna in kuntum mu/mineen","juz":4,"page":67},{"s":3,"a":140,"key":"3:140","ar":"إِن يَمْسَسْكُمْ قَرْحٌ فَقَدْ مَسَّ ٱلْقَوْمَ قَرْحٌ مِّثْلُهُۥ ۚ وَتِلْكَ ٱلْأَيَّامُ نُدَاوِلُهَا بَيْنَ ٱلنَّاسِ وَلِيَعْلَمَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَيَتَّخِذَ مِنكُمْ شُهَدَآءَ ۗ وَٱللَّهُ لَا يُحِبُّ ٱلظَّـٰلِمِينَ","en":"If a wound should touch you - there has already touched the [opposing] people a wound similar to it. And these days [of varying conditions] We alternate among the people so that Allāh may make evident those who believe and [may] take to Himself from among you martyrs - and Allāh does not like the wrongdoers -","tr":"In yamsaskum qarhun faqad massaalqawma qarhun mithluhu watilka al-ayyamu nudawiluhabayna annasi waliyaAAlama Allahu allatheenaamanoo wayattakhitha minkum shuhadaa wallahula yuhibbu aththalimeen","juz":4,"page":67},{"s":3,"a":141,"key":"3:141","ar":"وَلِيُمَحِّصَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَيَمْحَقَ ٱلْكَـٰفِرِينَ","en":"And that Allāh may purify the believers [through trials] and destroy the disbelievers.","tr":"Waliyumahhisa Allahuallatheena amanoo wayamhaqa alkafireen","juz":4,"page":68},{"s":3,"a":142,"key":"3:142","ar":"أَمْ حَسِبْتُمْ أَن تَدْخُلُوا۟ ٱلْجَنَّةَ وَلَمَّا يَعْلَمِ ٱللَّهُ ٱلَّذِينَ جَـٰهَدُوا۟ مِنكُمْ وَيَعْلَمَ ٱلصَّـٰبِرِينَ","en":"Or do you think that you will enter Paradise while Allāh has not yet made evident those of you who fight in His cause and made evident those who are steadfast?","tr":"Am hasibtum an tadkhuloo aljannatawalamma yaAAlami Allahu allatheena jahadoominkum wayaAAlama assabireen","juz":4,"page":68},{"s":3,"a":143,"key":"3:143","ar":"وَلَقَدْ كُنتُمْ تَمَنَّوْنَ ٱلْمَوْتَ مِن قَبْلِ أَن تَلْقَوْهُ فَقَدْ رَأَيْتُمُوهُ وَأَنتُمْ تَنظُرُونَ","en":"And you had certainly wished for death [i.e., martyrdom] before you encountered it, and you have [now] seen it [before you] while you were looking on.","tr":"Walaqad kuntum tamannawna almawta min qablian talqawhu faqad raaytumoohu waantum tanthuroon","juz":4,"page":68},{"s":3,"a":144,"key":"3:144","ar":"وَمَا مُحَمَّدٌ إِلَّا رَسُولٌ قَدْ خَلَتْ مِن قَبْلِهِ ٱلرُّسُلُ ۚ أَفَإِي۟ن مَّاتَ أَوْ قُتِلَ ٱنقَلَبْتُمْ عَلَىٰٓ أَعْقَـٰبِكُمْ ۚ وَمَن يَنقَلِبْ عَلَىٰ عَقِبَيْهِ فَلَن يَضُرَّ ٱللَّهَ شَيْـًٔا ۗ وَسَيَجْزِى ٱللَّهُ ٱلشَّـٰكِرِينَ","en":"Muḥammad is not but a messenger. [Other] messengers have passed on before him. So if he was to die or be killed, would you turn back on your heels [to unbelief]? And he who turns back on his heels will never harm Allāh at all; but Allāh will reward the grateful.","tr":"Wama muhammadun illarasoolun qad khalat min qablihi arrusulu afa-in mataaw qutila inqalabtum AAala aAAqabikum wamanyanqalib AAala AAaqibayhi falan yadurra Allahashay-an wasayajzee Allahu ashshakireen","juz":4,"page":68},{"s":3,"a":145,"key":"3:145","ar":"وَمَا كَانَ لِنَفْسٍ أَن تَمُوتَ إِلَّا بِإِذْنِ ٱللَّهِ كِتَـٰبًا مُّؤَجَّلًا ۗ وَمَن يُرِدْ ثَوَابَ ٱلدُّنْيَا نُؤْتِهِۦ مِنْهَا وَمَن يُرِدْ ثَوَابَ ٱلْـَٔاخِرَةِ نُؤْتِهِۦ مِنْهَا ۚ وَسَنَجْزِى ٱلشَّـٰكِرِينَ","en":"And it is not [possible] for one to die except by permission of Allāh at a decree determined. And whoever desires the reward of this world - We will give him thereof; and whoever desires the reward of the Hereafter - We will give him thereof. And We will reward the grateful.","tr":"Wama kana linafsin an tamootailla bi-ithni Allahi kitabanmu-ajjalan waman yurid thawaba addunyanu/tihi minha waman yurid thawaba al-akhiratinu/tihi minha wasanajzee ashshakireen","juz":4,"page":68},{"s":3,"a":146,"key":"3:146","ar":"وَكَأَيِّن مِّن نَّبِىٍّ قَـٰتَلَ مَعَهُۥ رِبِّيُّونَ كَثِيرٌ فَمَا وَهَنُوا۟ لِمَآ أَصَابَهُمْ فِى سَبِيلِ ٱللَّهِ وَمَا ضَعُفُوا۟ وَمَا ٱسْتَكَانُوا۟ ۗ وَٱللَّهُ يُحِبُّ ٱلصَّـٰبِرِينَ","en":"And how many a prophet [fought in battle and] with him fought many religious scholars. But they never lost assurance due to what afflicted them in the cause of Allāh, nor did they weaken or submit. And Allāh loves the steadfast.","tr":"Wakaayyin min nabiyyin qatalamaAAahu ribbiyyoona katheerun fama wahanoo lima asabahumfee sabeeli Allahi wama daAAufoo wamaistakanoo wallahu yuhibbu assabireen","juz":4,"page":68},{"s":3,"a":147,"key":"3:147","ar":"وَمَا كَانَ قَوْلَهُمْ إِلَّآ أَن قَالُوا۟ رَبَّنَا ٱغْفِرْ لَنَا ذُنُوبَنَا وَإِسْرَافَنَا فِىٓ أَمْرِنَا وَثَبِّتْ أَقْدَامَنَا وَٱنصُرْنَا عَلَى ٱلْقَوْمِ ٱلْكَـٰفِرِينَ","en":"And their words were not but that they said, \"Our Lord, forgive us our sins and the excess [committed] in our affairs and plant firmly our feet and give us victory over the disbelieving people.\"","tr":"Wama kana qawlahum illaan qaloo rabbana ighfir lana thunoobanawa-israfana fee amrina wathabbit aqdamanawansurna AAala alqawmi alkafireen","juz":4,"page":68},{"s":3,"a":148,"key":"3:148","ar":"فَـَٔاتَىٰهُمُ ٱللَّهُ ثَوَابَ ٱلدُّنْيَا وَحُسْنَ ثَوَابِ ٱلْـَٔاخِرَةِ ۗ وَٱللَّهُ يُحِبُّ ٱلْمُحْسِنِينَ","en":"So Allāh gave them the reward of this world and the good reward of the Hereafter. And Allāh loves the doers of good.","tr":"Faatahumu Allahu thawabaaddunya wahusna thawabi al-akhiratiwallahu yuhibbu almuhsineen","juz":4,"page":68},{"s":3,"a":149,"key":"3:149","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تُطِيعُوا۟ ٱلَّذِينَ كَفَرُوا۟ يَرُدُّوكُمْ عَلَىٰٓ أَعْقَـٰبِكُمْ فَتَنقَلِبُوا۟ خَـٰسِرِينَ","en":"O you who have believed, if you obey those who disbelieve, they will turn you back on your heels, and you will [then] become losers.","tr":"Ya ayyuha allatheena amanooin tuteeAAoo allatheena kafaroo yaruddookum AAalaaAAqabikum fatanqaliboo khasireen","juz":4,"page":69},{"s":3,"a":150,"key":"3:150","ar":"بَلِ ٱللَّهُ مَوْلَىٰكُمْ ۖ وَهُوَ خَيْرُ ٱلنَّـٰصِرِينَ","en":"But Allāh is your protector, and He is the best of helpers.","tr":"Bali Allahu mawlakum wahuwakhayru annasireen","juz":4,"page":69},{"s":3,"a":151,"key":"3:151","ar":"سَنُلْقِى فِى قُلُوبِ ٱلَّذِينَ كَفَرُوا۟ ٱلرُّعْبَ بِمَآ أَشْرَكُوا۟ بِٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ سُلْطَـٰنًا ۖ وَمَأْوَىٰهُمُ ٱلنَّارُ ۚ وَبِئْسَ مَثْوَى ٱلظَّـٰلِمِينَ","en":"We will cast terror into the hearts of those who disbelieve for what they have associated with Allāh of which He had not sent down [any] authority.1 And their refuge will be the Fire, and wretched is the residence of the wrongdoers.","tr":"Sanulqee fee quloobi allatheenakafaroo arruAAba bima ashrakoo billahima lam yunazzil bihi sultanan wama/wahumu annaruwabi/sa mathwa aththalimeen","juz":4,"page":69},{"s":3,"a":152,"key":"3:152","ar":"وَلَقَدْ صَدَقَكُمُ ٱللَّهُ وَعْدَهُۥٓ إِذْ تَحُسُّونَهُم بِإِذْنِهِۦ ۖ حَتَّىٰٓ إِذَا فَشِلْتُمْ وَتَنَـٰزَعْتُمْ فِى ٱلْأَمْرِ وَعَصَيْتُم مِّنۢ بَعْدِ مَآ أَرَىٰكُم مَّا تُحِبُّونَ ۚ مِنكُم مَّن يُرِيدُ ٱلدُّنْيَا وَمِنكُم مَّن يُرِيدُ ٱلْـَٔاخِرَةَ ۚ ثُمَّ صَرَفَكُمْ عَنْهُمْ لِيَبْتَلِيَكُمْ ۖ وَلَقَدْ عَفَا عَنكُمْ ۗ وَٱللَّهُ ذُو فَضْلٍ عَلَى ٱلْمُؤْمِنِينَ","en":"And Allāh had certainly fulfilled His promise to you when you were killing them [i.e., the enemy] by His permission until [the time] when you lost courage and fell to disputing about the order [given by the Prophet (ﷺ)] and disobeyed after He had shown you that which you love.1 Among you are some who desire this world, and among you are some who desire the Hereafter. Then He turned you back from them [defeated] that He might test you. And He has already forgiven you, and Allāh is the possessor of bounty for the believers.","tr":"Walaqad sadaqakumu AllahuwaAAdahu ith tahussoonahum bi-ithnihi hattaitha fashiltum watanazaAAtum fee al-amri waAAasaytummin baAAdi ma arakum ma tuhibboonaminkum man yureedu addunya waminkum man yureedual-akhirata thumma sarafakum AAanhum liyabtaliyakumwalaqad AAafa AAankum wallahu thoofadlin AAala almu/mineen","juz":4,"page":69},{"s":3,"a":153,"key":"3:153","ar":"۞ إِذْ تُصْعِدُونَ وَلَا تَلْوُۥنَ عَلَىٰٓ أَحَدٍ وَٱلرَّسُولُ يَدْعُوكُمْ فِىٓ أُخْرَىٰكُمْ فَأَثَـٰبَكُمْ غَمًّۢا بِغَمٍّ لِّكَيْلَا تَحْزَنُوا۟ عَلَىٰ مَا فَاتَكُمْ وَلَا مَآ أَصَـٰبَكُمْ ۗ وَٱللَّهُ خَبِيرٌۢ بِمَا تَعْمَلُونَ","en":"[Remember] when you [fled and] climbed [the mountain] without looking aside at anyone while the Messenger was calling you from behind. So Allāh repaid you with distress upon distress so you would not grieve for that which had escaped you [of victory and spoils of war] or [for] that which had befallen you [of injury and death]. And Allāh is [fully] Aware of what you do.","tr":"Ith tusAAidoona walatalwoona AAala ahadin warrasooluyadAAookum fee okhrakum faathabakum ghammanbighammin likay la tahzanoo AAala mafatakum wala ma asabakum wallahukhabeerun bima taAAmaloon","juz":4,"page":69},{"s":3,"a":154,"key":"3:154","ar":"ثُمَّ أَنزَلَ عَلَيْكُم مِّنۢ بَعْدِ ٱلْغَمِّ أَمَنَةً نُّعَاسًا يَغْشَىٰ طَآئِفَةً مِّنكُمْ ۖ وَطَآئِفَةٌ قَدْ أَهَمَّتْهُمْ أَنفُسُهُمْ يَظُنُّونَ بِٱللَّهِ غَيْرَ ٱلْحَقِّ ظَنَّ ٱلْجَـٰهِلِيَّةِ ۖ يَقُولُونَ هَل لَّنَا مِنَ ٱلْأَمْرِ مِن شَىْءٍ ۗ قُلْ إِنَّ ٱلْأَمْرَ كُلَّهُۥ لِلَّهِ ۗ يُخْفُونَ فِىٓ أَنفُسِهِم مَّا لَا يُبْدُونَ لَكَ ۖ يَقُولُونَ لَوْ كَانَ لَنَا مِنَ ٱلْأَمْرِ شَىْءٌ مَّا قُتِلْنَا هَـٰهُنَا ۗ قُل لَّوْ كُنتُمْ فِى بُيُوتِكُمْ لَبَرَزَ ٱلَّذِينَ كُتِبَ عَلَيْهِمُ ٱلْقَتْلُ إِلَىٰ مَضَاجِعِهِمْ ۖ وَلِيَبْتَلِىَ ٱللَّهُ مَا فِى صُدُورِكُمْ وَلِيُمَحِّصَ مَا فِى قُلُوبِكُمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"Then after distress, He sent down upon you security [in the form of] drowsiness, overcoming a faction of you, while another faction worried about themselves, thinking of Allāh other than the truth - the thought of ignorance, saying, \"Is there anything for us [to have done] in this matter?\" Say, \"Indeed, the matter belongs completely to Allāh.\" They conceal within themselves what they will not reveal to you. They say, \"If there was anything we could have done in the matter, we [i.e., some of us] would not have been killed right here.\" Say, \"Even if you had been inside your houses, those decreed to be killed would have come out to their death beds.\" [It was] so that Allāh might test what is in your breasts and purify what is in your hearts. And Allāh is Knowing of that within the breasts.","tr":"Thumma anzala AAalaykum min baAAdi alghammiamanatan nuAAasan yaghsha ta-ifatan minkumwata-ifatun qad ahammat-hum anfusuhum yathunnoonabillahi ghayra alhaqqi thannaaljahiliyyati yaqooloona hal lana mina al-amri minshay-in qul inna al-amra kullahu lillahi yukhfoona feeanfusihim ma la yubdoona laka yaqooloona law kanalana mina al-amri shay-on ma qutilna hahunaqul law kuntum fee buyootikum labaraza allatheena kutibaAAalayhimu alqatlu ila madajiAAihim waliyabtaliyaAllahu ma fee sudoorikum waliyumahhisama fee quloobikum wallahu AAaleemun bithatiassudoor","juz":4,"page":70},{"s":3,"a":155,"key":"3:155","ar":"إِنَّ ٱلَّذِينَ تَوَلَّوْا۟ مِنكُمْ يَوْمَ ٱلْتَقَى ٱلْجَمْعَانِ إِنَّمَا ٱسْتَزَلَّهُمُ ٱلشَّيْطَـٰنُ بِبَعْضِ مَا كَسَبُوا۟ ۖ وَلَقَدْ عَفَا ٱللَّهُ عَنْهُمْ ۗ إِنَّ ٱللَّهَ غَفُورٌ حَلِيمٌ","en":"Indeed, those of you who turned back on the day the two armies met [at Uḥud] - it was Satan who caused them to slip because of some [blame] they had earned. But Allāh has already forgiven them. Indeed, Allāh is Forgiving and Forbearing.","tr":"Inna allatheena tawallaw minkumyawma iltaqa aljamAAani innama istazallahumuashshaytanu bibaAAdi ma kasaboowalaqad AAafa Allahu AAanhum inna Allahaghafoorun haleem","juz":4,"page":70},{"s":3,"a":156,"key":"3:156","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَكُونُوا۟ كَٱلَّذِينَ كَفَرُوا۟ وَقَالُوا۟ لِإِخْوَٰنِهِمْ إِذَا ضَرَبُوا۟ فِى ٱلْأَرْضِ أَوْ كَانُوا۟ غُزًّى لَّوْ كَانُوا۟ عِندَنَا مَا مَاتُوا۟ وَمَا قُتِلُوا۟ لِيَجْعَلَ ٱللَّهُ ذَٰلِكَ حَسْرَةً فِى قُلُوبِهِمْ ۗ وَٱللَّهُ يُحْىِۦ وَيُمِيتُ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"O you who have believed, do not be like those who disbelieved and said about their brothers when they traveled through the land or went out to fight, \"If they had been with us, they would not have died or have been killed,\" so Allāh makes that [misconception] a regret within their hearts. And it is Allāh who gives life and causes death, and Allāh is Seeing of what you do.","tr":"Ya ayyuha allatheena amanoola takoonoo kallatheena kafaroo waqalooli-ikhwanihim itha daraboo fee al-ardiaw kanoo ghuzzan law kanoo AAindana mamatoo wama qutiloo liyajAAala Allahu thalikahasratan fee quloobihim wallahu yuhyeewayumeetu wallahu bima taAAmaloona baseer","juz":4,"page":70},{"s":3,"a":157,"key":"3:157","ar":"وَلَئِن قُتِلْتُمْ فِى سَبِيلِ ٱللَّهِ أَوْ مُتُّمْ لَمَغْفِرَةٌ مِّنَ ٱللَّهِ وَرَحْمَةٌ خَيْرٌ مِّمَّا يَجْمَعُونَ","en":"And if you are killed in the cause of Allāh or die - then forgiveness from Allāh and mercy are better than whatever they accumulate [in this world].","tr":"Wala-in qutiltum fee sabeeli Allahiaw muttum lamaghfiratun mina Allahi warahmatunkhayrun mimma yajmaAAoon","juz":4,"page":70},{"s":3,"a":158,"key":"3:158","ar":"وَلَئِن مُّتُّمْ أَوْ قُتِلْتُمْ لَإِلَى ٱللَّهِ تُحْشَرُونَ","en":"And whether you die or are killed, unto Allāh you will be gathered.","tr":"Wala-in muttum aw qutiltum la-ilaAllahi tuhsharoon","juz":4,"page":71},{"s":3,"a":159,"key":"3:159","ar":"فَبِمَا رَحْمَةٍ مِّنَ ٱللَّهِ لِنتَ لَهُمْ ۖ وَلَوْ كُنتَ فَظًّا غَلِيظَ ٱلْقَلْبِ لَٱنفَضُّوا۟ مِنْ حَوْلِكَ ۖ فَٱعْفُ عَنْهُمْ وَٱسْتَغْفِرْ لَهُمْ وَشَاوِرْهُمْ فِى ٱلْأَمْرِ ۖ فَإِذَا عَزَمْتَ فَتَوَكَّلْ عَلَى ٱللَّهِ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُتَوَكِّلِينَ","en":"So by mercy from Allāh, [O Muḥammad], you were lenient with them. And if you had been rude [in speech] and harsh in heart, they would have disbanded from about you. So pardon them and ask forgiveness for them and consult them in the matter. And when you have decided, then rely upon Allāh. Indeed, Allāh loves those who rely [upon Him].","tr":"Fabima rahmatin mina Allahilinta lahum walaw kunta faththan ghaleethaalqalbi lanfaddoo min hawlika faAAfuAAanhum wastaghfir lahum washawirhum fee al-amrifa-itha AAazamta fatawakkal AAala Allahiinna Allaha yuhibbu almutawakkileen","juz":4,"page":71},{"s":3,"a":160,"key":"3:160","ar":"إِن يَنصُرْكُمُ ٱللَّهُ فَلَا غَالِبَ لَكُمْ ۖ وَإِن يَخْذُلْكُمْ فَمَن ذَا ٱلَّذِى يَنصُرُكُم مِّنۢ بَعْدِهِۦ ۗ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ","en":"If Allāh should aid you, no one can overcome you; but if He should forsake you, who is there that can aid you after Him? And upon Allāh let the believers rely.","tr":"In yansurkumu Allahu falaghaliba lakum wa-in yakhthulkum faman thaallathee yansurukum min baAAdihi waAAala Allahifalyatawakkali almu/minoon","juz":4,"page":71},{"s":3,"a":161,"key":"3:161","ar":"وَمَا كَانَ لِنَبِىٍّ أَن يَغُلَّ ۚ وَمَن يَغْلُلْ يَأْتِ بِمَا غَلَّ يَوْمَ ٱلْقِيَـٰمَةِ ۚ ثُمَّ تُوَفَّىٰ كُلُّ نَفْسٍ مَّا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ","en":"It is not [attributable] to any prophet that he would act unfaithfully [in regard to war booty]. And whoever betrays, [taking unlawfully], will come with what he took on the Day of Resurrection. Then will every soul be [fully] compensated for what it earned, and they will not be wronged.","tr":"Wama kana linabiyyin anyaghulla waman yaghlul ya/ti bima ghalla yawma alqiyamatithumma tuwaffa kullu nafsin ma kasabat wahum layuthlamoon","juz":4,"page":71},{"s":3,"a":162,"key":"3:162","ar":"أَفَمَنِ ٱتَّبَعَ رِضْوَٰنَ ٱللَّهِ كَمَنۢ بَآءَ بِسَخَطٍ مِّنَ ٱللَّهِ وَمَأْوَىٰهُ جَهَنَّمُ ۚ وَبِئْسَ ٱلْمَصِيرُ","en":"So is one who pursues the pleasure of Allāh like one who brings upon himself the anger of Allāh and whose refuge is Hell? And wretched is the destination.","tr":"Afamani ittabaAAa ridwana Allahikaman baa bisakhatin mina Allahi wama/wahujahannamu wabi/sa almaseer","juz":4,"page":71},{"s":3,"a":163,"key":"3:163","ar":"هُمْ دَرَجَـٰتٌ عِندَ ٱللَّهِ ۗ وَٱللَّهُ بَصِيرٌۢ بِمَا يَعْمَلُونَ","en":"They are [varying] degrees in the sight of Allāh, and Allāh is Seeing of whatever they do.","tr":"Hum darajatun AAinda Allahiwallahu baseerun bima yaAAmaloon","juz":4,"page":71},{"s":3,"a":164,"key":"3:164","ar":"لَقَدْ مَنَّ ٱللَّهُ عَلَى ٱلْمُؤْمِنِينَ إِذْ بَعَثَ فِيهِمْ رَسُولًا مِّنْ أَنفُسِهِمْ يَتْلُوا۟ عَلَيْهِمْ ءَايَـٰتِهِۦ وَيُزَكِّيهِمْ وَيُعَلِّمُهُمُ ٱلْكِتَـٰبَ وَٱلْحِكْمَةَ وَإِن كَانُوا۟ مِن قَبْلُ لَفِى ضَلَـٰلٍ مُّبِينٍ","en":"Certainly did Allāh confer [great] favor upon the believers when He sent among them a Messenger from themselves, reciting to them His verses and purifying them and teaching them the Book [i.e., the Qur’ān] and wisdom,1 although they had been before in manifest error.","tr":"Laqad manna Allahu AAalaalmu/mineena ith baAAatha feehim rasoolan min anfusihimyatloo AAalayhim ayatihi wayuzakkeehimwayuAAallimuhumu alkitaba walhikmata wa-inkanoo min qablu lafee dalalin mubeen","juz":4,"page":71},{"s":3,"a":165,"key":"3:165","ar":"أَوَلَمَّآ أَصَـٰبَتْكُم مُّصِيبَةٌ قَدْ أَصَبْتُم مِّثْلَيْهَا قُلْتُمْ أَنَّىٰ هَـٰذَا ۖ قُلْ هُوَ مِنْ عِندِ أَنفُسِكُمْ ۗ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Why [is it that] when a [single] disaster struck you [on the day of Uḥud], although you had struck [the enemy in the battle of Badr] with one twice as great, you said, \"From where is this?\" Say, \"It is from yourselves [i.e., due to your sin].\" Indeed, Allāh is over all things competent.","tr":"Awa lamma asabatkum museebatunqad asabtum mithlayha qultum anna hathaqul huwa min AAindi anfusikum inna Allaha AAalakulli shay-in qadeer","juz":4,"page":71},{"s":3,"a":166,"key":"3:166","ar":"وَمَآ أَصَـٰبَكُمْ يَوْمَ ٱلْتَقَى ٱلْجَمْعَانِ فَبِإِذْنِ ٱللَّهِ وَلِيَعْلَمَ ٱلْمُؤْمِنِينَ","en":"And what struck you on the day the two armies met [at Uḥud] was by permission of Allāh that He might make evident the [true] believers","tr":"Wama asabakum yawma iltaqaaljamAAani fabi-ithni Allahi waliyaAAlamaalmu/mineen","juz":4,"page":72},{"s":3,"a":167,"key":"3:167","ar":"وَلِيَعْلَمَ ٱلَّذِينَ نَافَقُوا۟ ۚ وَقِيلَ لَهُمْ تَعَالَوْا۟ قَـٰتِلُوا۟ فِى سَبِيلِ ٱللَّهِ أَوِ ٱدْفَعُوا۟ ۖ قَالُوا۟ لَوْ نَعْلَمُ قِتَالًا لَّٱتَّبَعْنَـٰكُمْ ۗ هُمْ لِلْكُفْرِ يَوْمَئِذٍ أَقْرَبُ مِنْهُمْ لِلْإِيمَـٰنِ ۚ يَقُولُونَ بِأَفْوَٰهِهِم مَّا لَيْسَ فِى قُلُوبِهِمْ ۗ وَٱللَّهُ أَعْلَمُ بِمَا يَكْتُمُونَ","en":"And that He might make evident those who are hypocrites. For it was said to them, \"Come, fight in the way of Allāh or [at least] defend.\" They said, \"If we had known [there would be] battle, we would have followed you.\" They were nearer to disbelief that day than to faith, saying with their mouths what was not in their hearts. And Allāh is most knowing of what they conceal -","tr":"WaliyaAAlama allatheena nafaqoowaqeela lahum taAAalaw qatiloo fee sabeeli Allahiawi idfaAAoo qaloo law naAAlamu qitalan lattabaAAnakumhum lilkufri yawma-ithin aqrabu minhum lil-eemaniyaqooloona bi-afwahihim ma laysa fee quloobihim wallahuaAAlamu bima yaktumoon","juz":4,"page":72},{"s":3,"a":168,"key":"3:168","ar":"ٱلَّذِينَ قَالُوا۟ لِإِخْوَٰنِهِمْ وَقَعَدُوا۟ لَوْ أَطَاعُونَا مَا قُتِلُوا۟ ۗ قُلْ فَٱدْرَءُوا۟ عَنْ أَنفُسِكُمُ ٱلْمَوْتَ إِن كُنتُمْ صَـٰدِقِينَ","en":"Those who said about their brothers while sitting [at home], \"If they had obeyed us, they would not have been killed.\" Say, \"Then prevent death from yourselves, if you should be truthful.\"","tr":"Allatheena qaloo li-ikhwanihimwaqaAAadoo law ataAAoona ma qutiloo qul fadraooAAan anfusikumu almawta in kuntum sadiqeen","juz":4,"page":72},{"s":3,"a":169,"key":"3:169","ar":"وَلَا تَحْسَبَنَّ ٱلَّذِينَ قُتِلُوا۟ فِى سَبِيلِ ٱللَّهِ أَمْوَٰتًۢا ۚ بَلْ أَحْيَآءٌ عِندَ رَبِّهِمْ يُرْزَقُونَ","en":"And never think of those who have been killed in the cause of Allāh as dead. Rather, they are alive with their Lord, receiving provision,","tr":"Wala tahsabanna allatheenaqutiloo fee sabeeli Allahi amwatan bal ahyaonAAinda rabbihim yurzaqoon","juz":4,"page":72},{"s":3,"a":170,"key":"3:170","ar":"فَرِحِينَ بِمَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ وَيَسْتَبْشِرُونَ بِٱلَّذِينَ لَمْ يَلْحَقُوا۟ بِهِم مِّنْ خَلْفِهِمْ أَلَّا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"Rejoicing in what Allāh has bestowed upon them of His bounty, and they receive good tidings about those [to be martyred] after them who have not yet joined them - that there will be no fear concerning them, nor will they grieve.","tr":"Fariheena bima atahumuAllahu min fadlihi wayastabshiroona billatheenalam yalhaqoo bihim min khalfihim alla khawfunAAalayhim wala hum yahzanoon","juz":4,"page":72},{"s":3,"a":171,"key":"3:171","ar":"۞ يَسْتَبْشِرُونَ بِنِعْمَةٍ مِّنَ ٱللَّهِ وَفَضْلٍ وَأَنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُؤْمِنِينَ","en":"They receive good tidings of favor from Allāh and bounty and [of the fact] that Allāh does not allow the reward of believers to be lost -","tr":"Yastabshiroona biniAAmatin mina Allahiwafadlin waanna Allaha la yudeeAAuajra almu/mineen","juz":4,"page":72},{"s":3,"a":172,"key":"3:172","ar":"ٱلَّذِينَ ٱسْتَجَابُوا۟ لِلَّهِ وَٱلرَّسُولِ مِنۢ بَعْدِ مَآ أَصَابَهُمُ ٱلْقَرْحُ ۚ لِلَّذِينَ أَحْسَنُوا۟ مِنْهُمْ وَٱتَّقَوْا۟ أَجْرٌ عَظِيمٌ","en":"Those [believers] who responded to Allāh and the Messenger after injury had struck them. For those who did good among them and feared Allāh is a great reward -","tr":"Allatheena istajaboo lillahiwarrasooli min baAAdi ma asabahumu alqarhulillatheena ahsanoo minhum wattaqaw ajrunAAatheem","juz":4,"page":72},{"s":3,"a":173,"key":"3:173","ar":"ٱلَّذِينَ قَالَ لَهُمُ ٱلنَّاسُ إِنَّ ٱلنَّاسَ قَدْ جَمَعُوا۟ لَكُمْ فَٱخْشَوْهُمْ فَزَادَهُمْ إِيمَـٰنًا وَقَالُوا۟ حَسْبُنَا ٱللَّهُ وَنِعْمَ ٱلْوَكِيلُ","en":"Those to whom people [i.e., hypocrites] said, \"Indeed, the people have gathered against you, so fear them.\" But it [merely] increased them in faith, and they said, \"Sufficient for us is Allāh, and [He is] the best Disposer of affairs.\"1","tr":"Allatheena qala lahumu annasuinna annasa qad jamaAAoo lakum fakhshawhumfazadahum eemanan waqaloo hasbunaAllahu waniAAma alwakeel","juz":4,"page":72},{"s":3,"a":174,"key":"3:174","ar":"فَٱنقَلَبُوا۟ بِنِعْمَةٍ مِّنَ ٱللَّهِ وَفَضْلٍ لَّمْ يَمْسَسْهُمْ سُوٓءٌ وَٱتَّبَعُوا۟ رِضْوَٰنَ ٱللَّهِ ۗ وَٱللَّهُ ذُو فَضْلٍ عَظِيمٍ","en":"So they returned with favor from Allāh and bounty, no harm having touched them. And they pursued the pleasure of Allāh, and Allāh is the possessor of great bounty.","tr":"Fanqalaboo biniAAmatin mina Allahiwafadlin lam yamsas-hum soo-on wattabaAAoo ridwanaAllahi wallahu thoo fadlinAAatheem","juz":4,"page":73},{"s":3,"a":175,"key":"3:175","ar":"إِنَّمَا ذَٰلِكُمُ ٱلشَّيْطَـٰنُ يُخَوِّفُ أَوْلِيَآءَهُۥ فَلَا تَخَافُوهُمْ وَخَافُونِ إِن كُنتُم مُّؤْمِنِينَ","en":"That is only Satan who frightens [you] of his supporters. So fear them not, but fear Me, if you are [indeed] believers.","tr":"Innama thalikumu ashshaytanuyukhawwifu awliyaahu fala takhafoohum wakhafooniin kuntum mu/mineen","juz":4,"page":73},{"s":3,"a":176,"key":"3:176","ar":"وَلَا يَحْزُنكَ ٱلَّذِينَ يُسَـٰرِعُونَ فِى ٱلْكُفْرِ ۚ إِنَّهُمْ لَن يَضُرُّوا۟ ٱللَّهَ شَيْـًٔا ۗ يُرِيدُ ٱللَّهُ أَلَّا يَجْعَلَ لَهُمْ حَظًّا فِى ٱلْـَٔاخِرَةِ ۖ وَلَهُمْ عَذَابٌ عَظِيمٌ","en":"And do not be grieved, [O Muḥammad], by those who hasten into disbelief. Indeed, they will never harm Allāh at all. Allāh intends that He should give them no share in the Hereafter, and for them is a great punishment.","tr":"Wala yahzunka allatheenayusariAAoona fee alkufri innahum lan yadurroo Allahashay-an yureedu Allahu alla yajAAala lahum haththanfee al-akhirati walahum AAathabun AAatheem","juz":4,"page":73},{"s":3,"a":177,"key":"3:177","ar":"إِنَّ ٱلَّذِينَ ٱشْتَرَوُا۟ ٱلْكُفْرَ بِٱلْإِيمَـٰنِ لَن يَضُرُّوا۟ ٱللَّهَ شَيْـًٔا وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"Indeed, those who purchase disbelief [in exchange] for faith - never will they harm Allāh at all, and for them is a painful punishment.","tr":"Inna allatheena ishtarawoo alkufrabil-eemani lan yadurroo Allahashay-an walahum AAathabun aleem","juz":4,"page":73},{"s":3,"a":178,"key":"3:178","ar":"وَلَا يَحْسَبَنَّ ٱلَّذِينَ كَفَرُوٓا۟ أَنَّمَا نُمْلِى لَهُمْ خَيْرٌ لِّأَنفُسِهِمْ ۚ إِنَّمَا نُمْلِى لَهُمْ لِيَزْدَادُوٓا۟ إِثْمًا ۚ وَلَهُمْ عَذَابٌ مُّهِينٌ","en":"And let not those who disbelieve ever think that [because] We extend their time [of enjoyment] it is better for them. We only extend it for them so that they may increase in sin, and for them is a humiliating punishment.","tr":"Wala yahsabanna allatheenakafaroo annama numlee lahum khayrun li-anfusihim innamanumlee lahum liyazdadoo ithman walahum AAathabunmuheen","juz":4,"page":73},{"s":3,"a":179,"key":"3:179","ar":"مَّا كَانَ ٱللَّهُ لِيَذَرَ ٱلْمُؤْمِنِينَ عَلَىٰ مَآ أَنتُمْ عَلَيْهِ حَتَّىٰ يَمِيزَ ٱلْخَبِيثَ مِنَ ٱلطَّيِّبِ ۗ وَمَا كَانَ ٱللَّهُ لِيُطْلِعَكُمْ عَلَى ٱلْغَيْبِ وَلَـٰكِنَّ ٱللَّهَ يَجْتَبِى مِن رُّسُلِهِۦ مَن يَشَآءُ ۖ فَـَٔامِنُوا۟ بِٱللَّهِ وَرُسُلِهِۦ ۚ وَإِن تُؤْمِنُوا۟ وَتَتَّقُوا۟ فَلَكُمْ أَجْرٌ عَظِيمٌ","en":"Allāh would not leave the believers in that [state] you are in [presently] until He separates the evil from the good. Nor would Allāh reveal to you the unseen. But [instead], Allāh chooses of His messengers whom He wills, so believe in Allāh and His messengers. And if you believe and fear Him, then for you is a great reward.","tr":"Ma kana Allahu liyatharaalmu/mineena AAala ma antum AAalayhi hattayameeza alkhabeetha mina attayyibi wama kanaAllahu liyutliAAakum AAala alghaybi walakinnaAllaha yajtabee min rusulihi man yashao faaminoobillahi warusulihi wa-in tu/minoo watattaqoofalakum ajrun AAatheem","juz":4,"page":73},{"s":3,"a":180,"key":"3:180","ar":"وَلَا يَحْسَبَنَّ ٱلَّذِينَ يَبْخَلُونَ بِمَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ هُوَ خَيْرًا لَّهُم ۖ بَلْ هُوَ شَرٌّ لَّهُمْ ۖ سَيُطَوَّقُونَ مَا بَخِلُوا۟ بِهِۦ يَوْمَ ٱلْقِيَـٰمَةِ ۗ وَلِلَّهِ مِيرَٰثُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌ","en":"And let not those who [greedily] withhold what Allāh has given them of His bounty ever think that it is better for them. Rather, it is worse for them. Their necks will be encircled by what they withheld on the Day of Resurrection. And to Allāh belongs the heritage of the heavens and the earth. And Allāh, of what you do, is [fully] Aware.","tr":"Wala yahsabanna allatheenayabkhaloona bima atahummu Allahu minfadlihi huwa khayran lahum bal huwa sharrun lahum sayutawwaqoonama bakhiloo bihi yawma alqiyamati walillahimeerathu assamawati wal-ardiwallahu bima taAAmaloona khabeer","juz":4,"page":73},{"s":3,"a":181,"key":"3:181","ar":"لَّقَدْ سَمِعَ ٱللَّهُ قَوْلَ ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ فَقِيرٌ وَنَحْنُ أَغْنِيَآءُ ۘ سَنَكْتُبُ مَا قَالُوا۟ وَقَتْلَهُمُ ٱلْأَنۢبِيَآءَ بِغَيْرِ حَقٍّ وَنَقُولُ ذُوقُوا۟ عَذَابَ ٱلْحَرِيقِ","en":"Allāh has certainly heard the statement of those [Jews] who said, \"Indeed, Allāh is poor, while we are rich.\" We will record what they said and their killing of the prophets without right and will say, \"Taste the punishment of the Burning Fire.","tr":"Laqad samiAAa Allahu qawla allatheenaqaloo inna Allaha faqeerun wanahnu aghniyaonsanaktubu ma qaloo waqatlahumu al-anbiyaabighayri haqqin wanaqoolu thooqoo AAathabaalhareeq","juz":4,"page":74},{"s":3,"a":182,"key":"3:182","ar":"ذَٰلِكَ بِمَا قَدَّمَتْ أَيْدِيكُمْ وَأَنَّ ٱللَّهَ لَيْسَ بِظَلَّامٍ لِّلْعَبِيدِ","en":"That is for what your hands have put forth and because Allāh is not ever unjust to [His] servants.\"","tr":"Thalika bima qaddamataydeekum waanna Allaha laysa bithallaminlilAAabeed","juz":4,"page":74},{"s":3,"a":183,"key":"3:183","ar":"ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ عَهِدَ إِلَيْنَآ أَلَّا نُؤْمِنَ لِرَسُولٍ حَتَّىٰ يَأْتِيَنَا بِقُرْبَانٍ تَأْكُلُهُ ٱلنَّارُ ۗ قُلْ قَدْ جَآءَكُمْ رُسُلٌ مِّن قَبْلِى بِٱلْبَيِّنَـٰتِ وَبِٱلَّذِى قُلْتُمْ فَلِمَ قَتَلْتُمُوهُمْ إِن كُنتُمْ صَـٰدِقِينَ","en":"[They are] those who said, \"Indeed, Allāh has taken our promise not to believe any messenger until he brings us an offering which fire [from heaven] will consume.\" Say, \"There have already come to you messengers before me with clear proofs and [even] that of which you speak. So why did you kill them, if you should be truthful?\"","tr":"Allatheena qaloo inna AllahaAAahida ilayna alla nu/mina lirasoolin hattaya/tiyana biqurbanin ta/kuluhu annaruqul qad jaakum rusulun min qablee bilbayyinatiwabillathee qultum falima qataltumoohum in kutum sadiqeen","juz":4,"page":74},{"s":3,"a":184,"key":"3:184","ar":"فَإِن كَذَّبُوكَ فَقَدْ كُذِّبَ رُسُلٌ مِّن قَبْلِكَ جَآءُو بِٱلْبَيِّنَـٰتِ وَٱلزُّبُرِ وَٱلْكِتَـٰبِ ٱلْمُنِيرِ","en":"Then if they deny you, [O Muḥammad] - so were messengers denied before you, who brought clear proofs and written ordinances and the enlightening Scripture.1","tr":"Fa-in kaththabooka faqad kuththibarusulun min qablika jaoo bilbayyinati wazzuburiwalkitabi almuneer","juz":4,"page":74},{"s":3,"a":185,"key":"3:185","ar":"كُلُّ نَفْسٍ ذَآئِقَةُ ٱلْمَوْتِ ۗ وَإِنَّمَا تُوَفَّوْنَ أُجُورَكُمْ يَوْمَ ٱلْقِيَـٰمَةِ ۖ فَمَن زُحْزِحَ عَنِ ٱلنَّارِ وَأُدْخِلَ ٱلْجَنَّةَ فَقَدْ فَازَ ۗ وَمَا ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا مَتَـٰعُ ٱلْغُرُورِ","en":"Every soul will taste death, and you will only be given your [full] compensation on the Day of Resurrection. So he who is drawn away from the Fire and admitted to Paradise has attained [his desire]. And what is the life of this world except the enjoyment of delusion.","tr":"Kullu nafsin tha-iqatu almawtiwa-innama tuwaffawna ojoorakum yawma alqiyamatifaman zuhziha AAani annari waodkhilaaljannata faqad faza wama alhayatu addunyailla mataAAu alghuroor","juz":4,"page":74},{"s":3,"a":186,"key":"3:186","ar":"۞ لَتُبْلَوُنَّ فِىٓ أَمْوَٰلِكُمْ وَأَنفُسِكُمْ وَلَتَسْمَعُنَّ مِنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ مِن قَبْلِكُمْ وَمِنَ ٱلَّذِينَ أَشْرَكُوٓا۟ أَذًى كَثِيرًا ۚ وَإِن تَصْبِرُوا۟ وَتَتَّقُوا۟ فَإِنَّ ذَٰلِكَ مِنْ عَزْمِ ٱلْأُمُورِ","en":"You will surely be tested in your possessions and in yourselves. And you will surely hear from those who were given the Scripture before you and from those who associate others with Allāh much abuse. But if you are patient and fear Allāh - indeed, that is of the matters [worthy] of resolve.","tr":"Latublawunna fee amwalikumwaanfusikum walatasmaAAunna mina allatheena ootoo alkitabamin qablikum wamina allatheena ashrakoo athankatheeran wa-in tasbiroo watattaqoo fa-inna thalikamin AAazmi al-omoor","juz":4,"page":74},{"s":3,"a":187,"key":"3:187","ar":"وَإِذْ أَخَذَ ٱللَّهُ مِيثَـٰقَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ لَتُبَيِّنُنَّهُۥ لِلنَّاسِ وَلَا تَكْتُمُونَهُۥ فَنَبَذُوهُ وَرَآءَ ظُهُورِهِمْ وَٱشْتَرَوْا۟ بِهِۦ ثَمَنًا قَلِيلًا ۖ فَبِئْسَ مَا يَشْتَرُونَ","en":"And [mention, O Muḥammad], when Allāh took a covenant from those who were given the Scripture, [saying], \"You must make it clear [i.e., explain it] to the people and not conceal it.\" But they threw it away behind their backs and exchanged it for a small price. And wretched is that which they purchased.","tr":"Wa-ith akhatha Allahumeethaqa allatheena ootoo alkitabalatubayyinunnahu linnasi wala taktumoonahufanabathoohu waraa thuhoorihim washtarawbihi thamanan qaleelan fabi/sa ma yashtaroon","juz":4,"page":75},{"s":3,"a":188,"key":"3:188","ar":"لَا تَحْسَبَنَّ ٱلَّذِينَ يَفْرَحُونَ بِمَآ أَتَوا۟ وَّيُحِبُّونَ أَن يُحْمَدُوا۟ بِمَا لَمْ يَفْعَلُوا۟ فَلَا تَحْسَبَنَّهُم بِمَفَازَةٍ مِّنَ ٱلْعَذَابِ ۖ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"And never think that those who rejoice in what they have perpetrated and like to be praised for what they did not do - never think them [to be] in safety from the punishment, and for them is a painful punishment.","tr":"La tahsabanna allatheenayafrahoona bima ataw wayuhibboona an yuhmadoobima lam yafAAaloo fala tahsabannahum bimafazatinmina alAAathabi walahum AAathabun aleem","juz":4,"page":75},{"s":3,"a":189,"key":"3:189","ar":"وَلِلَّهِ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"And to Allāh belongs the dominion of the heavens and the earth, and Allāh is over all things competent.","tr":"Walillahi mulku assamawatiwal-ardi wallahu AAala kullishay-in qadeer","juz":4,"page":75},{"s":3,"a":190,"key":"3:190","ar":"إِنَّ فِى خَلْقِ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَٱخْتِلَـٰفِ ٱلَّيْلِ وَٱلنَّهَارِ لَـَٔايَـٰتٍ لِّأُو۟لِى ٱلْأَلْبَـٰبِ","en":"Indeed, in the creation of the heavens and the earth and the alternation of the night and the day are signs for those of understanding -","tr":"Inna fee khalqi assamawatiwal-ardi wakhtilafi allayli wannaharilaayatin li-olee al-albab","juz":4,"page":75},{"s":3,"a":191,"key":"3:191","ar":"ٱلَّذِينَ يَذْكُرُونَ ٱللَّهَ قِيَـٰمًا وَقُعُودًا وَعَلَىٰ جُنُوبِهِمْ وَيَتَفَكَّرُونَ فِى خَلْقِ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ رَبَّنَا مَا خَلَقْتَ هَـٰذَا بَـٰطِلًا سُبْحَـٰنَكَ فَقِنَا عَذَابَ ٱلنَّارِ","en":"Who remember Allāh while standing or sitting or [lying] on their sides and give thought to the creation of the heavens and the earth, [saying], \"Our Lord, You did not create this aimlessly; exalted are You [above such a thing]; then protect us from the punishment of the Fire.","tr":"Allatheena yathkuroona Allahaqiyaman waquAAoodan waAAala junoobihimwayatafakkaroona fee khalqi assamawati wal-ardirabbana ma khalaqta hatha batilan subhanakafaqina AAathaba annar","juz":4,"page":75},{"s":3,"a":192,"key":"3:192","ar":"رَبَّنَآ إِنَّكَ مَن تُدْخِلِ ٱلنَّارَ فَقَدْ أَخْزَيْتَهُۥ ۖ وَمَا لِلظَّـٰلِمِينَ مِنْ أَنصَارٍ","en":"Our Lord, indeed whoever You admit to the Fire - You have disgraced him, and for the wrongdoers there are no helpers.","tr":"Rabbana innaka man tudkhili annarafaqad akhzaytahu wama liththalimeenamin ansar","juz":4,"page":75},{"s":3,"a":193,"key":"3:193","ar":"رَّبَّنَآ إِنَّنَا سَمِعْنَا مُنَادِيًا يُنَادِى لِلْإِيمَـٰنِ أَنْ ءَامِنُوا۟ بِرَبِّكُمْ فَـَٔامَنَّا ۚ رَبَّنَا فَٱغْفِرْ لَنَا ذُنُوبَنَا وَكَفِّرْ عَنَّا سَيِّـَٔاتِنَا وَتَوَفَّنَا مَعَ ٱلْأَبْرَارِ","en":"Our Lord, indeed we have heard a caller [i.e., Prophet Muḥammad (ﷺ)] calling to faith, [saying], 'Believe in your Lord,' and we have believed. Our Lord, so forgive us our sins and remove from us our misdeeds and cause us to die among the righteous.","tr":"Rabbana innana samiAAnamunadiyan yunadee lil-eemani an aminoobirabbikum faamanna rabbana faghfirlana thunoobana wakaffir AAannasayyi-atina watawaffana maAAa al-abrar","juz":4,"page":75},{"s":3,"a":194,"key":"3:194","ar":"رَبَّنَا وَءَاتِنَا مَا وَعَدتَّنَا عَلَىٰ رُسُلِكَ وَلَا تُخْزِنَا يَوْمَ ٱلْقِيَـٰمَةِ ۗ إِنَّكَ لَا تُخْلِفُ ٱلْمِيعَادَ","en":"Our Lord, and grant us what You promised us through Your messengers and do not disgrace us on the Day of Resurrection. Indeed, You do not fail in [Your] promise.\"","tr":"Rabbana waatina mawaAAadtana AAala rusulika wala tukhzinayawma alqiyamati innaka la tukhlifu almeeAAad","juz":4,"page":75},{"s":3,"a":195,"key":"3:195","ar":"فَٱسْتَجَابَ لَهُمْ رَبُّهُمْ أَنِّى لَآ أُضِيعُ عَمَلَ عَـٰمِلٍ مِّنكُم مِّن ذَكَرٍ أَوْ أُنثَىٰ ۖ بَعْضُكُم مِّنۢ بَعْضٍ ۖ فَٱلَّذِينَ هَاجَرُوا۟ وَأُخْرِجُوا۟ مِن دِيَـٰرِهِمْ وَأُوذُوا۟ فِى سَبِيلِى وَقَـٰتَلُوا۟ وَقُتِلُوا۟ لَأُكَفِّرَنَّ عَنْهُمْ سَيِّـَٔاتِهِمْ وَلَأُدْخِلَنَّهُمْ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ثَوَابًا مِّنْ عِندِ ٱللَّهِ ۗ وَٱللَّهُ عِندَهُۥ حُسْنُ ٱلثَّوَابِ","en":"And their Lord responded to them, \"Never will I allow to be lost the work of [any] worker among you, whether male or female; you are of one another. So those who emigrated or were evicted from their homes or were harmed in My cause or fought or were killed - I will surely remove from them their misdeeds, and I will surely admit them to gardens beneath which rivers flow as reward from Allāh, and Allāh has with Him the best reward.\"","tr":"Fastajaba lahum rabbuhumannee la odeeAAu AAamala AAamilin minkum minthakarin aw ontha baAAdukum min baAAdinfallatheena hajaroo waokhrijoo min diyarihimwaoothoo fee sabeelee waqataloo waqutiloolaokaffiranna AAanhum sayyi-atihim walaodkhilannahum jannatintajree min tahtiha al-anharu thawabanmin AAindi Allahi wallahu AAindahu husnuaththawab","juz":4,"page":76},{"s":3,"a":196,"key":"3:196","ar":"لَا يَغُرَّنَّكَ تَقَلُّبُ ٱلَّذِينَ كَفَرُوا۟ فِى ٱلْبِلَـٰدِ","en":"Be not deceived by the [uninhibited] movement of the disbelievers throughout the land.","tr":"La yaghurrannaka taqallubu allatheenakafaroo fee albilad","juz":4,"page":76},{"s":3,"a":197,"key":"3:197","ar":"مَتَـٰعٌ قَلِيلٌ ثُمَّ مَأْوَىٰهُمْ جَهَنَّمُ ۚ وَبِئْسَ ٱلْمِهَادُ","en":"[It is but] a small enjoyment; then their [final] refuge is Hell, and wretched is the resting place.","tr":"MataAAun qaleelun thumma ma/wahumjahannamu wabi/sa almihad","juz":4,"page":76},{"s":3,"a":198,"key":"3:198","ar":"لَـٰكِنِ ٱلَّذِينَ ٱتَّقَوْا۟ رَبَّهُمْ لَهُمْ جَنَّـٰتٌ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا نُزُلًا مِّنْ عِندِ ٱللَّهِ ۗ وَمَا عِندَ ٱللَّهِ خَيْرٌ لِّلْأَبْرَارِ","en":"But those who feared their Lord will have gardens beneath which rivers flow, abiding eternally therein, as accommodation from Allāh. And that which is with Allāh is best for the righteous.","tr":"Lakini allatheena ittaqawrabbahum lahum jannatun tajree min tahtihaal-anharu khalideena feeha nuzulan minAAindi Allahi wama AAinda Allahi khayrunlil-abrar","juz":4,"page":76},{"s":3,"a":199,"key":"3:199","ar":"وَإِنَّ مِنْ أَهْلِ ٱلْكِتَـٰبِ لَمَن يُؤْمِنُ بِٱللَّهِ وَمَآ أُنزِلَ إِلَيْكُمْ وَمَآ أُنزِلَ إِلَيْهِمْ خَـٰشِعِينَ لِلَّهِ لَا يَشْتَرُونَ بِـَٔايَـٰتِ ٱللَّهِ ثَمَنًا قَلِيلًا ۗ أُو۟لَـٰٓئِكَ لَهُمْ أَجْرُهُمْ عِندَ رَبِّهِمْ ۗ إِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ","en":"And indeed, among the People of the Scripture are those who believe in Allāh and what was revealed to you and what was revealed to them, [being] humbly submissive to Allāh. They do not exchange the verses of Allāh for a small price. Those will have their reward with their Lord. Indeed, Allāh is swift in account.","tr":"Wa-inna min ahli alkitabi lamanyu/minu billahi wama onzila ilaykum wamaonzila ilayhim khashiAAeena lillahi layashtaroona bi-ayati Allahi thamananqaleelan ola-ika lahum ajruhum AAinda rabbihim inna AllahasareeAAu alhisab","juz":4,"page":76},{"s":3,"a":200,"key":"3:200","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱصْبِرُوا۟ وَصَابِرُوا۟ وَرَابِطُوا۟ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُفْلِحُونَ","en":"O you who have believed, persevere1 and endure2 and remain stationed3 and fear Allāh that you may be successful.","tr":"Ya ayyuha allatheena amanooisbiroo wasabiroo warabitoo wattaqooAllaha laAAallakum tuflihoon","juz":4,"page":76},{"s":4,"a":1,"key":"4:1","ar":" يَـٰٓأَيُّهَا ٱلنَّاسُ ٱتَّقُوا۟ رَبَّكُمُ ٱلَّذِى خَلَقَكُم مِّن نَّفْسٍ وَٰحِدَةٍ وَخَلَقَ مِنْهَا زَوْجَهَا وَبَثَّ مِنْهُمَا رِجَالًا كَثِيرًا وَنِسَآءً ۚ وَٱتَّقُوا۟ ٱللَّهَ ٱلَّذِى تَسَآءَلُونَ بِهِۦ وَٱلْأَرْحَامَ ۚ إِنَّ ٱللَّهَ كَانَ عَلَيْكُمْ رَقِيبًا","en":"O mankind, fear your Lord, who created you from one soul and created from it its mate and dispersed from both of them many men and women. And fear Allāh, through whom1 you ask one another,2 and the wombs.3 Indeed Allāh is ever,4 over you, an Observer.5","tr":"Ya ayyuha annasuittaqoo rabbakumu allathee khalaqakum min nafsin wahidatinwakhalaqa minha zawjaha wabaththa minhumarijalan katheeran wanisaan wattaqoo Allahaallathee tasaaloona bihi wal-arhamainna Allaha kana AAalaykum raqeeb","juz":4,"page":77},{"s":4,"a":2,"key":"4:2","ar":"وَءَاتُوا۟ ٱلْيَتَـٰمَىٰٓ أَمْوَٰلَهُمْ ۖ وَلَا تَتَبَدَّلُوا۟ ٱلْخَبِيثَ بِٱلطَّيِّبِ ۖ وَلَا تَأْكُلُوٓا۟ أَمْوَٰلَهُمْ إِلَىٰٓ أَمْوَٰلِكُمْ ۚ إِنَّهُۥ كَانَ حُوبًا كَبِيرًا","en":"And give to the orphans their properties and do not substitute the defective [of your own] for the good [of theirs]. And do not consume their properties into your own. Indeed, that is ever a great sin.","tr":"Waatoo alyatama amwalahumwala tatabaddaloo alkhabeetha bittayyibiwala ta/kuloo amwalahum ila amwalikuminnahu kana hooban kabeera","juz":4,"page":77},{"s":4,"a":3,"key":"4:3","ar":"وَإِنْ خِفْتُمْ أَلَّا تُقْسِطُوا۟ فِى ٱلْيَتَـٰمَىٰ فَٱنكِحُوا۟ مَا طَابَ لَكُم مِّنَ ٱلنِّسَآءِ مَثْنَىٰ وَثُلَـٰثَ وَرُبَـٰعَ ۖ فَإِنْ خِفْتُمْ أَلَّا تَعْدِلُوا۟ فَوَٰحِدَةً أَوْ مَا مَلَكَتْ أَيْمَـٰنُكُمْ ۚ ذَٰلِكَ أَدْنَىٰٓ أَلَّا تَعُولُوا۟","en":"And if you fear that you will not deal justly with the orphan girls, then marry those that please you of [other] women, two or three or four. But if you fear that you will not be just, then [marry only] one or those your right hands possess [i.e., slaves]. That is more suitable that you may not incline [to injustice].","tr":"Wa-in khiftum alla tuqsitoo feealyatama fankihoo ma tabalakum mina annisa-i mathna wathulathawarubaAAa fa-in khiftum alla taAAdiloo fawahidatanaw ma malakat aymanukum thalika adnaalla taAAooloo","juz":4,"page":77},{"s":4,"a":4,"key":"4:4","ar":"وَءَاتُوا۟ ٱلنِّسَآءَ صَدُقَـٰتِهِنَّ نِحْلَةً ۚ فَإِن طِبْنَ لَكُمْ عَن شَىْءٍ مِّنْهُ نَفْسًا فَكُلُوهُ هَنِيٓـًٔا مَّرِيٓـًٔا","en":"And give the women [upon marriage] their [bridal] gifts1 graciously. But if they give up willingly to you anything of it, then take it in satisfaction and ease.2","tr":"Waatoo annisaa saduqatihinnanihlatan fa-in tibna lakum AAan shay-in minhunafsan fakuloohu hanee-an maree-a","juz":4,"page":77},{"s":4,"a":5,"key":"4:5","ar":"وَلَا تُؤْتُوا۟ ٱلسُّفَهَآءَ أَمْوَٰلَكُمُ ٱلَّتِى جَعَلَ ٱللَّهُ لَكُمْ قِيَـٰمًا وَٱرْزُقُوهُمْ فِيهَا وَٱكْسُوهُمْ وَقُولُوا۟ لَهُمْ قَوْلًا مَّعْرُوفًا","en":"And do not give the weak-minded your property,1 which Allāh has made a means of sustenance for you, but provide for them with it and clothe them and speak to them words of appropriate kindness.","tr":"Wala tu/too assufahaaamwalakumu allatee jaAAala Allahu lakum qiyamanwarzuqoohum feeha waksoohum waqooloo lahumqawlan maAAroofa","juz":4,"page":77},{"s":4,"a":6,"key":"4:6","ar":"وَٱبْتَلُوا۟ ٱلْيَتَـٰمَىٰ حَتَّىٰٓ إِذَا بَلَغُوا۟ ٱلنِّكَاحَ فَإِنْ ءَانَسْتُم مِّنْهُمْ رُشْدًا فَٱدْفَعُوٓا۟ إِلَيْهِمْ أَمْوَٰلَهُمْ ۖ وَلَا تَأْكُلُوهَآ إِسْرَافًا وَبِدَارًا أَن يَكْبَرُوا۟ ۚ وَمَن كَانَ غَنِيًّا فَلْيَسْتَعْفِفْ ۖ وَمَن كَانَ فَقِيرًا فَلْيَأْكُلْ بِٱلْمَعْرُوفِ ۚ فَإِذَا دَفَعْتُمْ إِلَيْهِمْ أَمْوَٰلَهُمْ فَأَشْهِدُوا۟ عَلَيْهِمْ ۚ وَكَفَىٰ بِٱللَّهِ حَسِيبًا","en":"And test the orphans [in their abilities] until they reach marriageable age. Then if you perceive in them sound judgement, release their property to them. And do not consume it excessively and quickly, [anticipating] that they will grow up. And whoever, [when acting as guardian], is self-sufficient should refrain [from taking a fee]; and whoever is poor - let him take according to what is acceptable. Then when you release their property to them, bring witnesses upon them. And sufficient is Allāh as Accountant.","tr":"Wabtaloo alyatama hattaitha balaghoo annikaha fa-in anastumminhum rushdan fadfaAAoo ilayhim amwalahum walata/kulooha israfan wabidaran an yakbaroowaman kana ghaniyyan falyastaAAfif waman kanafaqeeran falya/kul bilmaAAroofi fa-itha dafaAAtumilayhim amwalahum faashhidoo AAalayhim wakafa billahihaseeba","juz":4,"page":77},{"s":4,"a":7,"key":"4:7","ar":"لِّلرِّجَالِ نَصِيبٌ مِّمَّا تَرَكَ ٱلْوَٰلِدَانِ وَٱلْأَقْرَبُونَ وَلِلنِّسَآءِ نَصِيبٌ مِّمَّا تَرَكَ ٱلْوَٰلِدَانِ وَٱلْأَقْرَبُونَ مِمَّا قَلَّ مِنْهُ أَوْ كَثُرَ ۚ نَصِيبًا مَّفْرُوضًا","en":"For men is a share of what the parents and close relatives leave, and for women is a share of what the parents and close relatives leave, be it little or much - an obligatory share.","tr":"Lirrijali naseebun mimmataraka alwalidani wal-aqraboona walinnisa-inaseebun mimma taraka alwalidani wal-aqraboonamimma qalla minhu aw kathura naseeban mafrooda","juz":4,"page":78},{"s":4,"a":8,"key":"4:8","ar":"وَإِذَا حَضَرَ ٱلْقِسْمَةَ أُو۟لُوا۟ ٱلْقُرْبَىٰ وَٱلْيَتَـٰمَىٰ وَٱلْمَسَـٰكِينُ فَٱرْزُقُوهُم مِّنْهُ وَقُولُوا۟ لَهُمْ قَوْلًا مَّعْرُوفًا","en":"And when [other] relatives and orphans and the needy are present at the [time of] division, then provide for them [something] out of it [i.e., the estate] and speak to them words of appropriate kindness.","tr":"Wa-itha hadara alqismataoloo alqurba walyatama walmasakeenufarzuqoohum minhu waqooloo lahum qawlan maAAroofa","juz":4,"page":78},{"s":4,"a":9,"key":"4:9","ar":"وَلْيَخْشَ ٱلَّذِينَ لَوْ تَرَكُوا۟ مِنْ خَلْفِهِمْ ذُرِّيَّةً ضِعَـٰفًا خَافُوا۟ عَلَيْهِمْ فَلْيَتَّقُوا۟ ٱللَّهَ وَلْيَقُولُوا۟ قَوْلًا سَدِيدًا","en":"And let those [executors and guardians] fear [injustice] as if they [themselves] had left weak offspring behind and feared for them. So let them fear Allāh and speak words of appropriate justice.","tr":"Walyakhsha allatheena law tarakoo minkhalfihim thurriyyatan diAAafan khafooAAalayhim falyattaqoo Allaha walyaqooloo qawlan sadeeda","juz":4,"page":78},{"s":4,"a":10,"key":"4:10","ar":"إِنَّ ٱلَّذِينَ يَأْكُلُونَ أَمْوَٰلَ ٱلْيَتَـٰمَىٰ ظُلْمًا إِنَّمَا يَأْكُلُونَ فِى بُطُونِهِمْ نَارًا ۖ وَسَيَصْلَوْنَ سَعِيرًا","en":"Indeed, those who devour the property of orphans unjustly are only consuming into their bellies fire. And they will be burned in a Blaze [i.e., Hellfire].","tr":"Inna allatheena ya/kuloona amwalaalyatama thulman innamaya/kuloona fee butoonihim naran wasayaslawnasaAAeera","juz":4,"page":78},{"s":4,"a":11,"key":"4:11","ar":"يُوصِيكُمُ ٱللَّهُ فِىٓ أَوْلَـٰدِكُمْ ۖ لِلذَّكَرِ مِثْلُ حَظِّ ٱلْأُنثَيَيْنِ ۚ فَإِن كُنَّ نِسَآءً فَوْقَ ٱثْنَتَيْنِ فَلَهُنَّ ثُلُثَا مَا تَرَكَ ۖ وَإِن كَانَتْ وَٰحِدَةً فَلَهَا ٱلنِّصْفُ ۚ وَلِأَبَوَيْهِ لِكُلِّ وَٰحِدٍ مِّنْهُمَا ٱلسُّدُسُ مِمَّا تَرَكَ إِن كَانَ لَهُۥ وَلَدٌ ۚ فَإِن لَّمْ يَكُن لَّهُۥ وَلَدٌ وَوَرِثَهُۥٓ أَبَوَاهُ فَلِأُمِّهِ ٱلثُّلُثُ ۚ فَإِن كَانَ لَهُۥٓ إِخْوَةٌ فَلِأُمِّهِ ٱلسُّدُسُ ۚ مِنۢ بَعْدِ وَصِيَّةٍ يُوصِى بِهَآ أَوْ دَيْنٍ ۗ ءَابَآؤُكُمْ وَأَبْنَآؤُكُمْ لَا تَدْرُونَ أَيُّهُمْ أَقْرَبُ لَكُمْ نَفْعًا ۚ فَرِيضَةً مِّنَ ٱللَّهِ ۗ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمًا","en":"Allāh instructs you concerning your children [i.e., their portions of inheritance]: for the male, what is equal to the share of two females. But if there are [only] daughters, two or more, for them is two thirds of one's estate.1 And if there is only one, for her is half. And for one's parents, to each one of them is a sixth of his estate if he left children. But if he had no children and the parents [alone] inherit from him, then for his mother is one third. And if he had brothers [and/or sisters], for his mother is a sixth,2 after any bequest he [may have] made or debt.3 Your parents or your children - you know not which of them are nearest to you in benefit. [These shares are] an obligation [imposed] by Allāh. Indeed, Allāh is ever Knowing and Wise.","tr":"Yooseekumu Allahu fee awladikumliththakari mithlu haththialonthayayni fa-in kunna nisaan fawqa ithnatayni falahunnathulutha ma taraka wa-in kanat wahidatanfalaha annisfu wali-abawayhi likulli wahidinminhuma assudusu mimma taraka in kanalahu waladun fa-in lam yakun lahu waladun wawarithahu abawahufali-ommihi aththuluthu fa-in kana lahu ikhwatunfali-ommihi assudusu min baAAdi wasiyyatin yooseebiha aw daynin abaokum waabnaokum latadroona ayyuhum aqrabu lakum nafAAan fareedatan mina Allahiinna Allaha kana AAaleeman hakeema","juz":4,"page":78},{"s":4,"a":12,"key":"4:12","ar":"۞ وَلَكُمْ نِصْفُ مَا تَرَكَ أَزْوَٰجُكُمْ إِن لَّمْ يَكُن لَّهُنَّ وَلَدٌ ۚ فَإِن كَانَ لَهُنَّ وَلَدٌ فَلَكُمُ ٱلرُّبُعُ مِمَّا تَرَكْنَ ۚ مِنۢ بَعْدِ وَصِيَّةٍ يُوصِينَ بِهَآ أَوْ دَيْنٍ ۚ وَلَهُنَّ ٱلرُّبُعُ مِمَّا تَرَكْتُمْ إِن لَّمْ يَكُن لَّكُمْ وَلَدٌ ۚ فَإِن كَانَ لَكُمْ وَلَدٌ فَلَهُنَّ ٱلثُّمُنُ مِمَّا تَرَكْتُم ۚ مِّنۢ بَعْدِ وَصِيَّةٍ تُوصُونَ بِهَآ أَوْ دَيْنٍ ۗ وَإِن كَانَ رَجُلٌ يُورَثُ كَلَـٰلَةً أَوِ ٱمْرَأَةٌ وَلَهُۥٓ أَخٌ أَوْ أُخْتٌ فَلِكُلِّ وَٰحِدٍ مِّنْهُمَا ٱلسُّدُسُ ۚ فَإِن كَانُوٓا۟ أَكْثَرَ مِن ذَٰلِكَ فَهُمْ شُرَكَآءُ فِى ٱلثُّلُثِ ۚ مِنۢ بَعْدِ وَصِيَّةٍ يُوصَىٰ بِهَآ أَوْ دَيْنٍ غَيْرَ مُضَآرٍّ ۚ وَصِيَّةً مِّنَ ٱللَّهِ ۗ وَٱللَّهُ عَلِيمٌ حَلِيمٌ","en":"And for you is half of what your wives leave if they have no child. But if they have a child, for you is one fourth of what they leave, after any bequest they [may have] made or debt. And for them [i.e., the wives] is one fourth if you leave no child. But if you leave a child, then for them is an eighth of what you leave, after any bequest you [may have] made or debt. And if a man or woman leaves neither ascendants nor descendants but has a brother or a sister, then for each one of them is a sixth. But if they are more than two, they share a third,1 after any bequest which was made or debt, as long as there is no detriment [caused].2 [This is] an ordinance from Allāh, and Allāh is Knowing and Forbearing.","tr":"Walakum nisfu ma taraka azwajukumin lam yakun lahunna waladun fa-in kana lahunna waladunfalakumu arrubuAAu mimma tarakna min baAAdi wasiyyatinyooseena biha aw daynin walahunna arrubuAAumimma taraktum in lam yakun lakum waladun fa-in kanalakum waladun falahunna aththumunu mimma taraktummin baAAdi wasiyyatin toosoona biha awdaynin wa-in kana rajulun yoorathu kalalatan awiimraatun walahu akhun aw okhtun falikulli wahidin minhumaassudusu fa-in kanoo akthara min thalikafahum shurakao fee aththuluthi min baAAdi wasiyyatinyoosa biha aw daynin ghayra mudarrin wasiyyatanmina Allahi wallahu AAaleemun haleem","juz":4,"page":79},{"s":4,"a":13,"key":"4:13","ar":"تِلْكَ حُدُودُ ٱللَّهِ ۚ وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ يُدْخِلْهُ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا ۚ وَذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"These are the limits [set by] Allāh, and whoever obeys Allāh and His Messenger will be admitted by Him to gardens [in Paradise] under which rivers flow, abiding eternally therein; and that is the great attainment.","tr":"Tilka hudoodu Allahi waman yutiAAiAllaha warasoolahu yudkhilhu jannatin tajree min tahtihaal-anharu khalideena feeha wathalikaalfawzu alAAatheem","juz":4,"page":79},{"s":4,"a":14,"key":"4:14","ar":"وَمَن يَعْصِ ٱللَّهَ وَرَسُولَهُۥ وَيَتَعَدَّ حُدُودَهُۥ يُدْخِلْهُ نَارًا خَـٰلِدًا فِيهَا وَلَهُۥ عَذَابٌ مُّهِينٌ","en":"And whoever disobeys Allāh and His Messenger and transgresses His limits - He will put him into the Fire to abide eternally therein, and he will have a humiliating punishment.","tr":"Waman yaAAsi Allahawarasoolahu wayataAAadda hudoodahu yudkhilhu narankhalidan feeha walahu AAathabun muheen","juz":4,"page":79},{"s":4,"a":15,"key":"4:15","ar":"وَٱلَّـٰتِى يَأْتِينَ ٱلْفَـٰحِشَةَ مِن نِّسَآئِكُمْ فَٱسْتَشْهِدُوا۟ عَلَيْهِنَّ أَرْبَعَةً مِّنكُمْ ۖ فَإِن شَهِدُوا۟ فَأَمْسِكُوهُنَّ فِى ٱلْبُيُوتِ حَتَّىٰ يَتَوَفَّىٰهُنَّ ٱلْمَوْتُ أَوْ يَجْعَلَ ٱللَّهُ لَهُنَّ سَبِيلًا","en":"Those who commit immorality [i.e., unlawful sexual intercourse] of your women - bring against them four [witnesses] from among you. And if they testify,1 confine them [i.e., the guilty women] to houses until death takes them or Allāh ordains for them [another] way.2","tr":"Wallatee ya/teena alfahishatamin nisa-ikum fastashhidoo AAalayhinna arbaAAatanminkum fa-in shahidoo faamsikoohunna fee albuyooti hattayatawaffahunna almawtu aw yajAAala Allahu lahunnasabeela","juz":4,"page":80},{"s":4,"a":16,"key":"4:16","ar":"وَٱلَّذَانِ يَأْتِيَـٰنِهَا مِنكُمْ فَـَٔاذُوهُمَا ۖ فَإِن تَابَا وَأَصْلَحَا فَأَعْرِضُوا۟ عَنْهُمَآ ۗ إِنَّ ٱللَّهَ كَانَ تَوَّابًا رَّحِيمًا","en":"And the two1 who commit it [i.e., unlawful sexual intercourse] among you - punish [i.e., dishonor] them both. But if they repent and correct themselves, leave them alone. Indeed, Allāh is ever Accepting of Repentance and Merciful.","tr":"Wallathani ya/tiyanihaminkum faathoohuma fa-in taba waaslahafaaAAridoo AAanhuma inna Allaha kanatawwaban raheema","juz":4,"page":80},{"s":4,"a":17,"key":"4:17","ar":"إِنَّمَا ٱلتَّوْبَةُ عَلَى ٱللَّهِ لِلَّذِينَ يَعْمَلُونَ ٱلسُّوٓءَ بِجَهَـٰلَةٍ ثُمَّ يَتُوبُونَ مِن قَرِيبٍ فَأُو۟لَـٰٓئِكَ يَتُوبُ ٱللَّهُ عَلَيْهِمْ ۗ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًا","en":"The repentance accepted by Allāh is only for those who do wrong in ignorance [or carelessness] and then repent soon [after].1 It is those to whom Allāh will turn in forgiveness, and Allāh is ever Knowing and Wise.","tr":"Innama attawbatu AAalaAllahi lillatheena yaAAmaloona assoo-abijahalatin thumma yatooboona min qareebin faola-ikayatoobu Allahu AAalayhim wakana AllahuAAaleeman hakeema","juz":4,"page":80},{"s":4,"a":18,"key":"4:18","ar":"وَلَيْسَتِ ٱلتَّوْبَةُ لِلَّذِينَ يَعْمَلُونَ ٱلسَّيِّـَٔاتِ حَتَّىٰٓ إِذَا حَضَرَ أَحَدَهُمُ ٱلْمَوْتُ قَالَ إِنِّى تُبْتُ ٱلْـَٔـٰنَ وَلَا ٱلَّذِينَ يَمُوتُونَ وَهُمْ كُفَّارٌ ۚ أُو۟لَـٰٓئِكَ أَعْتَدْنَا لَهُمْ عَذَابًا أَلِيمًا","en":"But repentance is not [accepted] of those who [continue to] do evil deeds up until, when death comes to one of them, he says, \"Indeed, I have repented now,\" or of those who die while they are disbelievers. For them We have prepared a painful punishment.","tr":"Walaysati attawbatu lillatheenayaAAmaloona assayyi-ati hatta ithahadara ahadahumu almawtu qala inneetubtu al-ana wala allatheena yamootoonawahum kuffarun ola-ika aAAtadna lahum AAathabanaleema","juz":4,"page":80},{"s":4,"a":19,"key":"4:19","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا يَحِلُّ لَكُمْ أَن تَرِثُوا۟ ٱلنِّسَآءَ كَرْهًا ۖ وَلَا تَعْضُلُوهُنَّ لِتَذْهَبُوا۟ بِبَعْضِ مَآ ءَاتَيْتُمُوهُنَّ إِلَّآ أَن يَأْتِينَ بِفَـٰحِشَةٍ مُّبَيِّنَةٍ ۚ وَعَاشِرُوهُنَّ بِٱلْمَعْرُوفِ ۚ فَإِن كَرِهْتُمُوهُنَّ فَعَسَىٰٓ أَن تَكْرَهُوا۟ شَيْـًٔا وَيَجْعَلَ ٱللَّهُ فِيهِ خَيْرًا كَثِيرًا","en":"O you who have believed, it is not lawful for you to inherit women by compulsion.1 And do not make difficulties for them in order to take [back] part of what you gave them2 unless they commit a clear immorality [i.e., adultery]. And live with them in kindness. For if you dislike them - perhaps you dislike a thing and Allāh makes therein much good.","tr":"Ya ayyuha allatheena amanoola yahillu lakum an tarithoo annisaakarhan wala taAAduloohunna litathhaboobibaAAdi ma ataytumoohunna illa anya/teena bifahishatin mubayyinatin waAAashiroohunnabilmaAAroofi fa-in karihtumoohunna faAAasa antakrahoo shay-an wayajAAala Allahu feehi khayran katheera","juz":4,"page":80},{"s":4,"a":20,"key":"4:20","ar":"وَإِنْ أَرَدتُّمُ ٱسْتِبْدَالَ زَوْجٍ مَّكَانَ زَوْجٍ وَءَاتَيْتُمْ إِحْدَىٰهُنَّ قِنطَارًا فَلَا تَأْخُذُوا۟ مِنْهُ شَيْـًٔا ۚ أَتَأْخُذُونَهُۥ بُهْتَـٰنًا وَإِثْمًا مُّبِينًا","en":"But if you want to replace one wife with another and you have given one of them a great amount [in gifts], do not take [back] from it anything. Would you take it in injustice and manifest sin?","tr":"Wa-in aradtumu istibdala zawjin makanazawjin waataytum ihdahunna qintaranfala ta/khuthoo minhu shay-an ata/khuthoonahubuhtanan wa-ithman mubeena","juz":4,"page":81},{"s":4,"a":21,"key":"4:21","ar":"وَكَيْفَ تَأْخُذُونَهُۥ وَقَدْ أَفْضَىٰ بَعْضُكُمْ إِلَىٰ بَعْضٍ وَأَخَذْنَ مِنكُم مِّيثَـٰقًا غَلِيظًا","en":"And how could you take it while you have gone in unto each other and they have taken from you a solemn covenant?","tr":"Wakayfa ta/khuthoonahu waqad afdabaAAdukum ila baAAdin waakhathnaminkum meethaqan ghaleetha","juz":4,"page":81},{"s":4,"a":22,"key":"4:22","ar":"وَلَا تَنكِحُوا۟ مَا نَكَحَ ءَابَآؤُكُم مِّنَ ٱلنِّسَآءِ إِلَّا مَا قَدْ سَلَفَ ۚ إِنَّهُۥ كَانَ فَـٰحِشَةً وَمَقْتًا وَسَآءَ سَبِيلًا","en":"And do not marry those [women] whom your fathers married, except what has already occurred.1 Indeed, it was an immorality and hateful [to Allāh] and was evil as a way.","tr":"Wala tankihoo ma nakahaabaokum mina annisa-i illa maqad salafa innahu kana fahishatan wamaqtan wasaasabeela","juz":4,"page":81},{"s":4,"a":23,"key":"4:23","ar":"حُرِّمَتْ عَلَيْكُمْ أُمَّهَـٰتُكُمْ وَبَنَاتُكُمْ وَأَخَوَٰتُكُمْ وَعَمَّـٰتُكُمْ وَخَـٰلَـٰتُكُمْ وَبَنَاتُ ٱلْأَخِ وَبَنَاتُ ٱلْأُخْتِ وَأُمَّهَـٰتُكُمُ ٱلَّـٰتِىٓ أَرْضَعْنَكُمْ وَأَخَوَٰتُكُم مِّنَ ٱلرَّضَـٰعَةِ وَأُمَّهَـٰتُ نِسَآئِكُمْ وَرَبَـٰٓئِبُكُمُ ٱلَّـٰتِى فِى حُجُورِكُم مِّن نِّسَآئِكُمُ ٱلَّـٰتِى دَخَلْتُم بِهِنَّ فَإِن لَّمْ تَكُونُوا۟ دَخَلْتُم بِهِنَّ فَلَا جُنَاحَ عَلَيْكُمْ وَحَلَـٰٓئِلُ أَبْنَآئِكُمُ ٱلَّذِينَ مِنْ أَصْلَـٰبِكُمْ وَأَن تَجْمَعُوا۟ بَيْنَ ٱلْأُخْتَيْنِ إِلَّا مَا قَدْ سَلَفَ ۗ إِنَّ ٱللَّهَ كَانَ غَفُورًا رَّحِيمًا","en":"Prohibited to you [for marriage] are your mothers, your daughters, your sisters, your father's sisters, your mother's sisters, your brother's daughters, your sister's daughters, your [milk] mothers who nursed you, your sisters through nursing, your wives' mothers, and your step-daughters under your guardianship [born] of your wives unto whom you have gone in. But if you have not gone in unto them, there is no sin upon you. And [also prohibited are] the wives of your sons who are from your [own] loins, and that you take [in marriage] two sisters simultaneously, except for what has already occurred.1 Indeed, Allāh is ever Forgiving and Merciful.","tr":"Hurrimat AAalaykum ommahatukumwabanatukum waakhawatukum waAAammatukum wakhalatukumwabanatu al-akhi wabanatu al-okhti waommahatukumuallatee ardaAAnakum waakhawatukum mina arradaAAatiwaommahatu nisa-ikum waraba-ibukumu allateefee hujoorikum min nisa-ikumu allateedakhaltum bihinna fa-in lam takoonoo dakhaltum bihinna falajunaha AAalaykum wahala-ilu abna-ikumuallatheena min aslabikum waan tajmaAAoobayna al-okhtayni illa ma qad salafa inna Allahakana ghafooran raheema","juz":4,"page":81},{"s":4,"a":24,"key":"4:24","ar":"۞ وَٱلْمُحْصَنَـٰتُ مِنَ ٱلنِّسَآءِ إِلَّا مَا مَلَكَتْ أَيْمَـٰنُكُمْ ۖ كِتَـٰبَ ٱللَّهِ عَلَيْكُمْ ۚ وَأُحِلَّ لَكُم مَّا وَرَآءَ ذَٰلِكُمْ أَن تَبْتَغُوا۟ بِأَمْوَٰلِكُم مُّحْصِنِينَ غَيْرَ مُسَـٰفِحِينَ ۚ فَمَا ٱسْتَمْتَعْتُم بِهِۦ مِنْهُنَّ فَـَٔاتُوهُنَّ أُجُورَهُنَّ فَرِيضَةً ۚ وَلَا جُنَاحَ عَلَيْكُمْ فِيمَا تَرَٰضَيْتُم بِهِۦ مِنۢ بَعْدِ ٱلْفَرِيضَةِ ۚ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمًا","en":"And [also prohibited to you are all] married women except those your right hands possess.1 [This is] the decree of Allāh upon you. And lawful to you are [all others] beyond these, [provided] that you seek them [in marriage] with [gifts from] your property, desiring chastity, not unlawful sexual intercourse. So for whatever you enjoy [of marriage] from them, give them their due compensation2 as an obligation. And there is no blame upon you for what you mutually agree to beyond the obligation. Indeed, Allāh is ever Knowing and Wise.","tr":"Walmuhsanatu mina annisa-iilla ma malakat aymanukum kitaba AllahiAAalaykum waohilla lakum ma waraa thalikuman tabtaghoo bi-amwalikum muhsineena ghayra musafiheenafama istamtaAAtum bihi minhunna faatoohunnaojoorahunna fareedatan wala junaha AAalaykumfeema taradaytum bihi min baAAdi alfareedatiinna Allaha kana AAaleeman hakeema","juz":5,"page":82},{"s":4,"a":25,"key":"4:25","ar":"وَمَن لَّمْ يَسْتَطِعْ مِنكُمْ طَوْلًا أَن يَنكِحَ ٱلْمُحْصَنَـٰتِ ٱلْمُؤْمِنَـٰتِ فَمِن مَّا مَلَكَتْ أَيْمَـٰنُكُم مِّن فَتَيَـٰتِكُمُ ٱلْمُؤْمِنَـٰتِ ۚ وَٱللَّهُ أَعْلَمُ بِإِيمَـٰنِكُم ۚ بَعْضُكُم مِّنۢ بَعْضٍ ۚ فَٱنكِحُوهُنَّ بِإِذْنِ أَهْلِهِنَّ وَءَاتُوهُنَّ أُجُورَهُنَّ بِٱلْمَعْرُوفِ مُحْصَنَـٰتٍ غَيْرَ مُسَـٰفِحَـٰتٍ وَلَا مُتَّخِذَٰتِ أَخْدَانٍ ۚ فَإِذَآ أُحْصِنَّ فَإِنْ أَتَيْنَ بِفَـٰحِشَةٍ فَعَلَيْهِنَّ نِصْفُ مَا عَلَى ٱلْمُحْصَنَـٰتِ مِنَ ٱلْعَذَابِ ۚ ذَٰلِكَ لِمَنْ خَشِىَ ٱلْعَنَتَ مِنكُمْ ۚ وَأَن تَصْبِرُوا۟ خَيْرٌ لَّكُمْ ۗ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"And whoever among you cannot [find] the means to marry free, believing women, then [he may marry] from those whom your right hands possess of believing slave girls. And Allāh is most knowing about your faith. You [believers] are of one another. So marry them with the permission of their people and give them their due compensation [i.e., mahr] according to what is acceptable. [They should be] chaste, neither [of] those who commit unlawful intercourse randomly nor those who take [secret] lovers. But once they are sheltered in marriage, if they should commit adultery, then for them is half the punishment for free [unmarried] women. This [allowance] is for him among you who fears affliction [i.e., sin], but to be patient is better for you. And Allāh is Forgiving and Merciful.","tr":"Waman lam yastatiAA minkum tawlanan yankiha almuhsanati almu/minatifamin ma malakat aymanukum min fatayatikumualmu/minati wallahu aAAlamu bi-eemanikumbaAAdukum min baAAdin fankihoohunnabi-ithni ahlihinna waatoohunna ojoorahunna bilmaAAroofimuhsanatin ghayra masafihatin walamuttakhithati akhdanin fa-itha ohsinnafa-in atayna bifahishatin faAAalayhinna nisfu maAAala almuhsanati mina alAAathabi thalikaliman khashiya alAAanata minkum waan tasbiroo khayrunlakum wallahu ghafoorun raheem","juz":5,"page":82},{"s":4,"a":26,"key":"4:26","ar":"يُرِيدُ ٱللَّهُ لِيُبَيِّنَ لَكُمْ وَيَهْدِيَكُمْ سُنَنَ ٱلَّذِينَ مِن قَبْلِكُمْ وَيَتُوبَ عَلَيْكُمْ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"Allāh wants to make clear to you [the lawful from the unlawful] and guide you to the [good] practices of those before you and to accept your repentance. And Allāh is Knowing and Wise.","tr":"Yureedu Allahu liyubayyina lakumwayahdiyakum sunana allatheena min qablikum wayatoobaAAalaykum wallahu AAaleemun hakeem","juz":5,"page":82},{"s":4,"a":27,"key":"4:27","ar":"وَٱللَّهُ يُرِيدُ أَن يَتُوبَ عَلَيْكُمْ وَيُرِيدُ ٱلَّذِينَ يَتَّبِعُونَ ٱلشَّهَوَٰتِ أَن تَمِيلُوا۟ مَيْلًا عَظِيمًا","en":"Allāh wants to accept your repentance, but those who follow [their] passions want you to digress [into] a great deviation.","tr":"Wallahu yureedu an yatoobaAAalaykum wayureedu allatheena yattabiAAoona ashshahawatian tameeloo maylan AAatheem","juz":5,"page":83},{"s":4,"a":28,"key":"4:28","ar":"يُرِيدُ ٱللَّهُ أَن يُخَفِّفَ عَنكُمْ ۚ وَخُلِقَ ٱلْإِنسَـٰنُ ضَعِيفًا","en":"And Allāh wants to lighten for you [your difficulties]; and mankind was created weak.","tr":"Yureedu Allahu an yukhaffifa AAankumwakhuliqa al-insanu daAAeefa","juz":5,"page":83},{"s":4,"a":29,"key":"4:29","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَأْكُلُوٓا۟ أَمْوَٰلَكُم بَيْنَكُم بِٱلْبَـٰطِلِ إِلَّآ أَن تَكُونَ تِجَـٰرَةً عَن تَرَاضٍ مِّنكُمْ ۚ وَلَا تَقْتُلُوٓا۟ أَنفُسَكُمْ ۚ إِنَّ ٱللَّهَ كَانَ بِكُمْ رَحِيمًا","en":"O you who have believed, do not consume one another's wealth unjustly1 but only [in lawful] business by mutual consent. And do not kill yourselves [or one another]. Indeed, Allāh is to you ever Merciful.","tr":"Ya ayyuha allatheena amanoola ta/kuloo amwalakum baynakum bilbatiliilla an takoona tijaratan AAan taradinminkum wala taqtuloo anfusakum inna Allaha kanabikum raheema","juz":5,"page":83},{"s":4,"a":30,"key":"4:30","ar":"وَمَن يَفْعَلْ ذَٰلِكَ عُدْوَٰنًا وَظُلْمًا فَسَوْفَ نُصْلِيهِ نَارًا ۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرًا","en":"And whoever does that in aggression and injustice - then We will drive him into a Fire. And that, for Allāh, is [always] easy.","tr":"Waman yafAAal thalika AAudwananwathulman fasawfa nusleehi naran wakanathalika AAala Allahi yaseera","juz":5,"page":83},{"s":4,"a":31,"key":"4:31","ar":"إِن تَجْتَنِبُوا۟ كَبَآئِرَ مَا تُنْهَوْنَ عَنْهُ نُكَفِّرْ عَنكُمْ سَيِّـَٔاتِكُمْ وَنُدْخِلْكُم مُّدْخَلًا كَرِيمًا","en":"If you avoid the major sins which you are forbidden, We will remove from you your lesser sins and admit you to a noble entrance [into Paradise].","tr":"In tajtaniboo kaba-ira matunhawna AAanhu nukaffir AAankum sayyi-atikum wanudkhilkummudkhalan kareema","juz":5,"page":83},{"s":4,"a":32,"key":"4:32","ar":"وَلَا تَتَمَنَّوْا۟ مَا فَضَّلَ ٱللَّهُ بِهِۦ بَعْضَكُمْ عَلَىٰ بَعْضٍ ۚ لِّلرِّجَالِ نَصِيبٌ مِّمَّا ٱكْتَسَبُوا۟ ۖ وَلِلنِّسَآءِ نَصِيبٌ مِّمَّا ٱكْتَسَبْنَ ۚ وَسْـَٔلُوا۟ ٱللَّهَ مِن فَضْلِهِۦٓ ۗ إِنَّ ٱللَّهَ كَانَ بِكُلِّ شَىْءٍ عَلِيمًا","en":"And do not wish for that by which Allāh has made some of you exceed others. For men is a share of what they have earned, and for women is a share of1 what they have earned. And ask Allāh of His bounty. Indeed Allāh is ever, of all things, Knowing.","tr":"Wala tatamannaw ma faddalaAllahu bihi baAAdakum AAala baAAdinlirrijali naseebun mimma iktasaboowalinnisa-i naseebun mimma iktasabnawas-aloo Allaha min fadlihi inna Allahakana bikulli shay-in AAaleema","juz":5,"page":83},{"s":4,"a":33,"key":"4:33","ar":"وَلِكُلٍّ جَعَلْنَا مَوَٰلِىَ مِمَّا تَرَكَ ٱلْوَٰلِدَانِ وَٱلْأَقْرَبُونَ ۚ وَٱلَّذِينَ عَقَدَتْ أَيْمَـٰنُكُمْ فَـَٔاتُوهُمْ نَصِيبَهُمْ ۚ إِنَّ ٱللَّهَ كَانَ عَلَىٰ كُلِّ شَىْءٍ شَهِيدًا","en":"And for all, We have made heirs to what is left by parents and relatives. And to those whom your oaths have bound [to you] - give them their share.1 Indeed Allāh is ever, over all things, a Witness.","tr":"Walikullin jaAAalna mawaliyamimma taraka alwalidani wal-aqraboonawallatheena AAaqadat aymanukum faatoohumnaseebahum inna Allaha kana AAalakulli shay-in shaheeda","juz":5,"page":83},{"s":4,"a":34,"key":"4:34","ar":"ٱلرِّجَالُ قَوَّٰمُونَ عَلَى ٱلنِّسَآءِ بِمَا فَضَّلَ ٱللَّهُ بَعْضَهُمْ عَلَىٰ بَعْضٍ وَبِمَآ أَنفَقُوا۟ مِنْ أَمْوَٰلِهِمْ ۚ فَٱلصَّـٰلِحَـٰتُ قَـٰنِتَـٰتٌ حَـٰفِظَـٰتٌ لِّلْغَيْبِ بِمَا حَفِظَ ٱللَّهُ ۚ وَٱلَّـٰتِى تَخَافُونَ نُشُوزَهُنَّ فَعِظُوهُنَّ وَٱهْجُرُوهُنَّ فِى ٱلْمَضَاجِعِ وَٱضْرِبُوهُنَّ ۖ فَإِنْ أَطَعْنَكُمْ فَلَا تَبْغُوا۟ عَلَيْهِنَّ سَبِيلًا ۗ إِنَّ ٱللَّهَ كَانَ عَلِيًّا كَبِيرًا","en":"Men are in charge of women1 by [right of] what Allāh has given one over the other and what they spend [for maintenance] from their wealth. So righteous women are devoutly obedient, guarding in [the husband's] absence what Allāh would have them guard.2 But those [wives] from whom you fear arrogance3 - [first] advise them; [then if they persist], forsake them in bed; and [finally], strike them [lightly].4 But if they obey you [once more], seek no means against them. Indeed, Allāh is ever Exalted and Grand.","tr":"Arrijalu qawwamoonaAAala annisa-i bima faddalaAllahu baAAdahum AAala baAAdin wabimaanfaqoo min amwalihim fassalihatu qanitatunhafithatun lilghaybi bima hafithaAllahu wallatee takhafoonanushoozahunna faAAithoohunna wahjuroohunnafee almadajiAAi wadriboohunna fa-in ataAAnakumfala tabghoo AAalayhinna sabeelan inna Allaha kanaAAaliyyan kabeera","juz":5,"page":84},{"s":4,"a":35,"key":"4:35","ar":"وَإِنْ خِفْتُمْ شِقَاقَ بَيْنِهِمَا فَٱبْعَثُوا۟ حَكَمًا مِّنْ أَهْلِهِۦ وَحَكَمًا مِّنْ أَهْلِهَآ إِن يُرِيدَآ إِصْلَـٰحًا يُوَفِّقِ ٱللَّهُ بَيْنَهُمَآ ۗ إِنَّ ٱللَّهَ كَانَ عَلِيمًا خَبِيرًا","en":"And if you fear dissension between the two, send an arbitrator from his people and an arbitrator from her people. If they both desire reconciliation, Allāh will cause it between them. Indeed, Allāh is ever Knowing and Aware.","tr":"Wa-in khiftum shiqaqa baynihimafabAAathoo hakaman min ahlihi wahakaman minahliha in yureeda islahan yuwaffiqiAllahu baynahuma inna Allaha kanaAAaleeman khabeera","juz":5,"page":84},{"s":4,"a":36,"key":"4:36","ar":"۞ وَٱعْبُدُوا۟ ٱللَّهَ وَلَا تُشْرِكُوا۟ بِهِۦ شَيْـًٔا ۖ وَبِٱلْوَٰلِدَيْنِ إِحْسَـٰنًا وَبِذِى ٱلْقُرْبَىٰ وَٱلْيَتَـٰمَىٰ وَٱلْمَسَـٰكِينِ وَٱلْجَارِ ذِى ٱلْقُرْبَىٰ وَٱلْجَارِ ٱلْجُنُبِ وَٱلصَّاحِبِ بِٱلْجَنۢبِ وَٱبْنِ ٱلسَّبِيلِ وَمَا مَلَكَتْ أَيْمَـٰنُكُمْ ۗ إِنَّ ٱللَّهَ لَا يُحِبُّ مَن كَانَ مُخْتَالًا فَخُورًا","en":"Worship Allāh and associate nothing with Him, and to parents do good, and to relatives, orphans, the needy, the near neighbor, the neighbor farther away, the companion at your side,1 the traveler, and those whom your right hands possess. Indeed, Allāh does not like those who are self-deluding and boastful,","tr":"WaAAbudoo Allaha walatushrikoo bihi shay-an wabilwalidayni ihsananwabithee alqurba walyatama walmasakeeniwaljari thee alqurba waljarialjunubi wassahibi biljanbi wabniassabeeli wama malakat aymanukum inna Allahala yuhibbu man kana mukhtalan fakhoora","juz":5,"page":84},{"s":4,"a":37,"key":"4:37","ar":"ٱلَّذِينَ يَبْخَلُونَ وَيَأْمُرُونَ ٱلنَّاسَ بِٱلْبُخْلِ وَيَكْتُمُونَ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ ۗ وَأَعْتَدْنَا لِلْكَـٰفِرِينَ عَذَابًا مُّهِينًا","en":"Who are stingy and enjoin upon [other] people stinginess and conceal what Allāh has given them of His bounty - and We have prepared for the disbelievers a humiliating punishment -","tr":"Allatheena yabkhaloona waya/muroona annasabilbukhli wayaktumoona ma atahumuAllahu min fadlihi waaAAtadna lilkafireenaAAathaban muheena","juz":5,"page":84},{"s":4,"a":38,"key":"4:38","ar":"وَٱلَّذِينَ يُنفِقُونَ أَمْوَٰلَهُمْ رِئَآءَ ٱلنَّاسِ وَلَا يُؤْمِنُونَ بِٱللَّهِ وَلَا بِٱلْيَوْمِ ٱلْـَٔاخِرِ ۗ وَمَن يَكُنِ ٱلشَّيْطَـٰنُ لَهُۥ قَرِينًا فَسَآءَ قَرِينًا","en":"And [also] those who spend of their wealth to be seen by the people and believe not in Allāh nor in the Last Day. And he to whom Satan is a companion - then evil is he as a companion.","tr":"Wallatheena yunfiqoona amwalahumri-aa annasi wala yu/minoona billahiwala bilyawmi al-akhiri waman yakuni ashshaytanulahu qareenan fasaa qareena","juz":5,"page":85},{"s":4,"a":39,"key":"4:39","ar":"وَمَاذَا عَلَيْهِمْ لَوْ ءَامَنُوا۟ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ وَأَنفَقُوا۟ مِمَّا رَزَقَهُمُ ٱللَّهُ ۚ وَكَانَ ٱللَّهُ بِهِمْ عَلِيمًا","en":"And what [harm would come] upon them if they believed in Allāh and the Last Day and spent out of what Allāh provided for them? And Allāh is ever, about them, Knowing.","tr":"Wamatha AAalayhim law amanoobillahi walyawmi al-akhiriwaanfaqoo mimma razaqahumu Allahu wakana Allahubihim AAaleema","juz":5,"page":85},{"s":4,"a":40,"key":"4:40","ar":"إِنَّ ٱللَّهَ لَا يَظْلِمُ مِثْقَالَ ذَرَّةٍ ۖ وَإِن تَكُ حَسَنَةً يُضَـٰعِفْهَا وَيُؤْتِ مِن لَّدُنْهُ أَجْرًا عَظِيمًا","en":"Indeed, Allāh does not do injustice, [even] as much as an atom's weight; while if there is a good deed, He multiplies it and gives from Himself a great reward.","tr":"Inna Allaha la yathlimumithqala tharratin wa-in taku hasanatan yudaAAifhawayu/ti min ladunhu ajran AAatheema","juz":5,"page":85},{"s":4,"a":41,"key":"4:41","ar":"فَكَيْفَ إِذَا جِئْنَا مِن كُلِّ أُمَّةٍۭ بِشَهِيدٍ وَجِئْنَا بِكَ عَلَىٰ هَـٰٓؤُلَآءِ شَهِيدًا","en":"So how [will it be] when We bring from every nation a witness and We bring you, [O Muḥammad], against these [people] as a witness?","tr":"Fakayfa itha ji/na min kulliommatin bishaheedin waji/na bika AAala haola-ishaheeda","juz":5,"page":85},{"s":4,"a":42,"key":"4:42","ar":"يَوْمَئِذٍ يَوَدُّ ٱلَّذِينَ كَفَرُوا۟ وَعَصَوُا۟ ٱلرَّسُولَ لَوْ تُسَوَّىٰ بِهِمُ ٱلْأَرْضُ وَلَا يَكْتُمُونَ ٱللَّهَ حَدِيثًا","en":"That Day, those who disbelieved and disobeyed the Messenger will wish they could be covered by the earth. And they will not conceal from Allāh a [single] statement.","tr":"Yawma-ithin yawaddu allatheenakafaroo waAAasawoo arrasoola law tusawwabihimu al-ardu wala yaktumoona Allaha hadeetha","juz":5,"page":85},{"s":4,"a":43,"key":"4:43","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَقْرَبُوا۟ ٱلصَّلَوٰةَ وَأَنتُمْ سُكَـٰرَىٰ حَتَّىٰ تَعْلَمُوا۟ مَا تَقُولُونَ وَلَا جُنُبًا إِلَّا عَابِرِى سَبِيلٍ حَتَّىٰ تَغْتَسِلُوا۟ ۚ وَإِن كُنتُم مَّرْضَىٰٓ أَوْ عَلَىٰ سَفَرٍ أَوْ جَآءَ أَحَدٌ مِّنكُم مِّنَ ٱلْغَآئِطِ أَوْ لَـٰمَسْتُمُ ٱلنِّسَآءَ فَلَمْ تَجِدُوا۟ مَآءً فَتَيَمَّمُوا۟ صَعِيدًا طَيِّبًا فَٱمْسَحُوا۟ بِوُجُوهِكُمْ وَأَيْدِيكُمْ ۗ إِنَّ ٱللَّهَ كَانَ عَفُوًّا غَفُورًا","en":"O you who have believed, do not approach prayer while you are intoxicated until you know what you are saying1 or in a state of janābah,2 except those passing through [a place of prayer], until you have washed [your whole body]. And if you are ill or on a journey or one of you comes from the place of relieving himself or you have contacted women [i.e., had sexual intercourse] and find no water, then seek clean earth and wipe over your faces and your hands [with it]. Indeed, Allāh is ever Pardoning3 and Forgiving.","tr":"Ya ayyuha allatheena amanoola taqraboo assalata waantum sukarahatta taAAlamoo ma taqooloona walajunuban illa AAabiree sabeelin hattataghtasiloo wa-in kuntum marda aw AAala safarin awjaa ahadun minkum mina algha-iti aw lamastumuannisaa falam tajidoo maan fatayammamoo saAAeedantayyiban famsahoo biwujoohikum waaydeekuminna Allaha kana AAafuwwan ghafoora","juz":5,"page":85},{"s":4,"a":44,"key":"4:44","ar":"أَلَمْ تَرَ إِلَى ٱلَّذِينَ أُوتُوا۟ نَصِيبًا مِّنَ ٱلْكِتَـٰبِ يَشْتَرُونَ ٱلضَّلَـٰلَةَ وَيُرِيدُونَ أَن تَضِلُّوا۟ ٱلسَّبِيلَ","en":"Have you not seen those who were given a portion of the Scripture, purchasing error [in exchange for it] and wishing you would lose the way?","tr":"Alam tara ila allatheena ootoonaseeban mina alkitabi yashtaroona addalalatawayureedoona an tadilloo assabeel","juz":5,"page":85},{"s":4,"a":45,"key":"4:45","ar":"وَٱللَّهُ أَعْلَمُ بِأَعْدَآئِكُمْ ۚ وَكَفَىٰ بِٱللَّهِ وَلِيًّا وَكَفَىٰ بِٱللَّهِ نَصِيرًا","en":"And Allāh is most knowing of your enemies; and sufficient is Allāh as an ally, and sufficient is Allāh as a helper.","tr":"Wallahu aAAlamu bi-aAAda-ikumwakafa billahi waliyyan wakafa billahinaseera","juz":5,"page":86},{"s":4,"a":46,"key":"4:46","ar":"مِّنَ ٱلَّذِينَ هَادُوا۟ يُحَرِّفُونَ ٱلْكَلِمَ عَن مَّوَاضِعِهِۦ وَيَقُولُونَ سَمِعْنَا وَعَصَيْنَا وَٱسْمَعْ غَيْرَ مُسْمَعٍ وَرَٰعِنَا لَيًّۢا بِأَلْسِنَتِهِمْ وَطَعْنًا فِى ٱلدِّينِ ۚ وَلَوْ أَنَّهُمْ قَالُوا۟ سَمِعْنَا وَأَطَعْنَا وَٱسْمَعْ وَٱنظُرْنَا لَكَانَ خَيْرًا لَّهُمْ وَأَقْوَمَ وَلَـٰكِن لَّعَنَهُمُ ٱللَّهُ بِكُفْرِهِمْ فَلَا يُؤْمِنُونَ إِلَّا قَلِيلًا","en":"Among the Jews are those who distort words from their [proper] places [i.e., usages] and say, \"We hear and disobey\" and \"Hear but be not heard\" and \"Rāʿinā,\"1 twisting their tongues and defaming the religion. And if they had said [instead], \"We hear and obey\" and \"Wait for us [to understand],\" it would have been better for them and more suitable. But Allāh has cursed them for their disbelief, so they believe not, except for a few.2","tr":"Mina allatheena hadoo yuharrifoonaalkalima AAan mawadiAAihi wayaqooloona samiAAnawaAAasayna wasmaAA ghayra musmaAAin waraAAinalayyan bi-alsinatihim wataAAnan fee addeeni walawannahum qaloo samiAAna waataAAna wasmaAAwanthurna lakana khayranlahum waaqwama walakin laAAanahumu Allahubikufrihim fala yu/minoona illa qaleela","juz":5,"page":86},{"s":4,"a":47,"key":"4:47","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ ءَامِنُوا۟ بِمَا نَزَّلْنَا مُصَدِّقًا لِّمَا مَعَكُم مِّن قَبْلِ أَن نَّطْمِسَ وُجُوهًا فَنَرُدَّهَا عَلَىٰٓ أَدْبَارِهَآ أَوْ نَلْعَنَهُمْ كَمَا لَعَنَّآ أَصْحَـٰبَ ٱلسَّبْتِ ۚ وَكَانَ أَمْرُ ٱللَّهِ مَفْعُولًا","en":"O you who were given the Scripture, believe in what We have sent down [to Prophet Muḥammad (ﷺ)], confirming that which is with you, before We obliterate faces and turn them toward their backs or curse them as We cursed the sabbath-breakers.1 And ever is the matter [i.e., decree] of Allāh accomplished.","tr":"Ya ayyuha allatheenaootoo alkitaba aminoo bima nazzalnamusaddiqan lima maAAakum min qabli an natmisawujoohan fanaruddaha AAala adbarihaaw nalAAanahum kama laAAanna as-habaassabti wakana amru Allahi mafAAoola","juz":5,"page":86},{"s":4,"a":48,"key":"4:48","ar":"إِنَّ ٱللَّهَ لَا يَغْفِرُ أَن يُشْرَكَ بِهِۦ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَآءُ ۚ وَمَن يُشْرِكْ بِٱللَّهِ فَقَدِ ٱفْتَرَىٰٓ إِثْمًا عَظِيمًا","en":"Indeed, Allāh does not forgive association with Him, but He forgives what is less than that for whom He wills. And he who associates others with Allāh has certainly fabricated a tremendous sin.","tr":"Inna Allaha la yaghfiru anyushraka bihi wayaghfiru ma doona thalika limanyashao waman yushrik billahi faqadi iftaraithman AAatheema","juz":5,"page":86},{"s":4,"a":49,"key":"4:49","ar":"أَلَمْ تَرَ إِلَى ٱلَّذِينَ يُزَكُّونَ أَنفُسَهُم ۚ بَلِ ٱللَّهُ يُزَكِّى مَن يَشَآءُ وَلَا يُظْلَمُونَ فَتِيلًا","en":"Have you not seen those who claim themselves to be pure? Rather, Allāh purifies whom He wills, and injustice is not done to them, [even] as much as a thread [inside a date seed].","tr":"Alam tara ila allatheenayuzakkoona anfusahum bali Allahu yuzakkee man yashaowala yuthlamoona fateela","juz":5,"page":86},{"s":4,"a":50,"key":"4:50","ar":"ٱنظُرْ كَيْفَ يَفْتَرُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ ۖ وَكَفَىٰ بِهِۦٓ إِثْمًا مُّبِينًا","en":"Look how they invent about Allāh untruth, and sufficient is that as a manifest sin.","tr":"Onthur kayfa yaftaroona AAalaAllahi alkathiba wakafa bihi ithman mubeena","juz":5,"page":86},{"s":4,"a":51,"key":"4:51","ar":"أَلَمْ تَرَ إِلَى ٱلَّذِينَ أُوتُوا۟ نَصِيبًا مِّنَ ٱلْكِتَـٰبِ يُؤْمِنُونَ بِٱلْجِبْتِ وَٱلطَّـٰغُوتِ وَيَقُولُونَ لِلَّذِينَ كَفَرُوا۟ هَـٰٓؤُلَآءِ أَهْدَىٰ مِنَ ٱلَّذِينَ ءَامَنُوا۟ سَبِيلًا","en":"Have you not seen those who were given a portion of the Scripture, who believe in jibt [superstition] and ṭāghūt [false objects of worship] and say about the disbelievers, \"These are better guided than the believers as to the way\"?","tr":"Alam tara ila allatheena ootoonaseeban mina alkitabi yu/minoona biljibtiwattaghooti wayaqooloona lillatheenakafaroo haola-i ahda mina allatheena amanoosabeela","juz":5,"page":86},{"s":4,"a":52,"key":"4:52","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ لَعَنَهُمُ ٱللَّهُ ۖ وَمَن يَلْعَنِ ٱللَّهُ فَلَن تَجِدَ لَهُۥ نَصِيرًا","en":"Those are the ones whom Allāh has cursed; and he whom Allāh curses - never will you find for him a helper.","tr":"Ola-ika allatheena laAAanahumuAllahu waman yalAAani Allahu falan tajida lahu naseera","juz":5,"page":87},{"s":4,"a":53,"key":"4:53","ar":"أَمْ لَهُمْ نَصِيبٌ مِّنَ ٱلْمُلْكِ فَإِذًا لَّا يُؤْتُونَ ٱلنَّاسَ نَقِيرًا","en":"Or have they a share of dominion? Then [if that were so], they would not give the people [even as much as] the speck on a date seed.","tr":"Am lahum naseebun mina almulki fa-ithanla yu/toona annasa naqeera","juz":5,"page":87},{"s":4,"a":54,"key":"4:54","ar":"أَمْ يَحْسُدُونَ ٱلنَّاسَ عَلَىٰ مَآ ءَاتَىٰهُمُ ٱللَّهُ مِن فَضْلِهِۦ ۖ فَقَدْ ءَاتَيْنَآ ءَالَ إِبْرَٰهِيمَ ٱلْكِتَـٰبَ وَٱلْحِكْمَةَ وَءَاتَيْنَـٰهُم مُّلْكًا عَظِيمًا","en":"Or do they envy people for what Allāh has given them of His bounty? But We had already given the family of Abraham the Scripture and wisdom1 and conferred upon them a great kingdom.","tr":"Am yahsudoona annasaAAala ma atahumu Allahu min fadlihifaqad atayna ala ibraheema alkitabawalhikmata waataynahum mulkan AAatheema","juz":5,"page":87},{"s":4,"a":55,"key":"4:55","ar":"فَمِنْهُم مَّنْ ءَامَنَ بِهِۦ وَمِنْهُم مَّن صَدَّ عَنْهُ ۚ وَكَفَىٰ بِجَهَنَّمَ سَعِيرًا","en":"And some among them believed in it,1 and some among them were averse to it. And sufficient is Hell as a blaze.","tr":"Faminhum man amana bihi waminhum man saddaAAanhu wakafa bijahannama saAAeera","juz":5,"page":87},{"s":4,"a":56,"key":"4:56","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ بِـَٔايَـٰتِنَا سَوْفَ نُصْلِيهِمْ نَارًا كُلَّمَا نَضِجَتْ جُلُودُهُم بَدَّلْنَـٰهُمْ جُلُودًا غَيْرَهَا لِيَذُوقُوا۟ ٱلْعَذَابَ ۗ إِنَّ ٱللَّهَ كَانَ عَزِيزًا حَكِيمًا","en":"Indeed, those who disbelieve in Our verses - We will drive them into a fire. Every time their skins are roasted through, We will replace them with other skins so they may taste the punishment. Indeed, Allāh is ever Exalted in Might and Wise.","tr":"Inna allatheena kafaroo bi-ayatinasawfa nusleehim naran kullama nadijatjulooduhum baddalnahum juloodan ghayraha liyathooqooalAAathaba inna Allaha kana AAazeezan hakeema","juz":5,"page":87},{"s":4,"a":57,"key":"4:57","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ سَنُدْخِلُهُمْ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَدًا ۖ لَّهُمْ فِيهَآ أَزْوَٰجٌ مُّطَهَّرَةٌ ۖ وَنُدْخِلُهُمْ ظِلًّا ظَلِيلًا","en":"But those who believe and do righteous deeds - We will admit them to gardens beneath which rivers flow, wherein they abide forever. For them therein are purified spouses, and We will admit them to deepening shade.","tr":"Wallatheena amanoowaAAamiloo assalihati sanudkhiluhum jannatintajree min tahtiha al-anharu khalideenafeeha abadan lahum feeha azwajun mutahharatunwanudkhiluhum thillan thaleela","juz":5,"page":87},{"s":4,"a":58,"key":"4:58","ar":"۞ إِنَّ ٱللَّهَ يَأْمُرُكُمْ أَن تُؤَدُّوا۟ ٱلْأَمَـٰنَـٰتِ إِلَىٰٓ أَهْلِهَا وَإِذَا حَكَمْتُم بَيْنَ ٱلنَّاسِ أَن تَحْكُمُوا۟ بِٱلْعَدْلِ ۚ إِنَّ ٱللَّهَ نِعِمَّا يَعِظُكُم بِهِۦٓ ۗ إِنَّ ٱللَّهَ كَانَ سَمِيعًۢا بَصِيرًا","en":"Indeed, Allāh commands you to render trusts to whom they are due and when you judge between people to judge with justice. Excellent is that which Allāh instructs you. Indeed, Allāh is ever Hearing and Seeing.","tr":"Inna Allaha ya/murukum an tu-addooal-amanati ila ahliha wa-itha hakamtumbayna annasi an tahkumoo bilAAadliinna Allaha niAAimma yaAAithukum bihiinna Allaha kana sameeAAan baseera","juz":5,"page":87},{"s":4,"a":59,"key":"4:59","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ وَأُو۟لِى ٱلْأَمْرِ مِنكُمْ ۖ فَإِن تَنَـٰزَعْتُمْ فِى شَىْءٍ فَرُدُّوهُ إِلَى ٱللَّهِ وَٱلرَّسُولِ إِن كُنتُمْ تُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ ۚ ذَٰلِكَ خَيْرٌ وَأَحْسَنُ تَأْوِيلًا","en":"O you who have believed, obey Allāh and obey the Messenger and those in authority among you. And if you disagree over anything, refer it to Allāh and the Messenger, if you should believe in Allāh and the Last Day. That is the best [way] and best in result.","tr":"Ya ayyuha allatheena amanooateeAAoo Allaha waateeAAoo arrasoolawaolee al-amri minkum fa-in tanazaAAtum fee shay-infaruddoohu ila Allahi warrasooli in kuntumtu/minoona billahi walyawmi al-akhirithalika khayrun waahsanu ta/weela","juz":5,"page":87},{"s":4,"a":60,"key":"4:60","ar":"أَلَمْ تَرَ إِلَى ٱلَّذِينَ يَزْعُمُونَ أَنَّهُمْ ءَامَنُوا۟ بِمَآ أُنزِلَ إِلَيْكَ وَمَآ أُنزِلَ مِن قَبْلِكَ يُرِيدُونَ أَن يَتَحَاكَمُوٓا۟ إِلَى ٱلطَّـٰغُوتِ وَقَدْ أُمِرُوٓا۟ أَن يَكْفُرُوا۟ بِهِۦ وَيُرِيدُ ٱلشَّيْطَـٰنُ أَن يُضِلَّهُمْ ضَلَـٰلًۢا بَعِيدًا","en":"Have you not seen those who claim to have believed in what was revealed to you, [O Muḥammad], and what was revealed before you? They wish to refer legislation to ṭāghūt,1 while they were commanded to reject it; and Satan wishes to lead them far astray.","tr":"Alam tara ila allatheenayazAAumoona annahum amanoo bima onzila ilayka wamaonzila min qablika yureedoona an yatahakamoo ila attaghootiwaqad omiroo an yakfuroo bihi wayureedu ashshaytanuan yudillahum dalalan baAAeeda","juz":5,"page":88},{"s":4,"a":61,"key":"4:61","ar":"وَإِذَا قِيلَ لَهُمْ تَعَالَوْا۟ إِلَىٰ مَآ أَنزَلَ ٱللَّهُ وَإِلَى ٱلرَّسُولِ رَأَيْتَ ٱلْمُنَـٰفِقِينَ يَصُدُّونَ عَنكَ صُدُودًا","en":"And when it is said to them, \"Come to what Allāh has revealed and to the Messenger,\" you see the hypocrites turning away from you in aversion.","tr":"Wa-itha qeela lahum taAAalawila ma anzala Allahu wa-ila arrasooliraayta almunafiqeena yasuddoona AAanka sudooda","juz":5,"page":88},{"s":4,"a":62,"key":"4:62","ar":"فَكَيْفَ إِذَآ أَصَـٰبَتْهُم مُّصِيبَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ ثُمَّ جَآءُوكَ يَحْلِفُونَ بِٱللَّهِ إِنْ أَرَدْنَآ إِلَّآ إِحْسَـٰنًا وَتَوْفِيقًا","en":"So how [will it be] when disaster strikes them because of what their hands have put forth and then they come to you swearing by Allāh, \"We intended nothing but good conduct and accommodation.\"","tr":"Fakayfa itha asabat-hum museebatunbima qaddamat aydeehim thumma jaooka yahlifoonabillahi in aradna illa ihsananwatawfeeqa","juz":5,"page":88},{"s":4,"a":63,"key":"4:63","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ يَعْلَمُ ٱللَّهُ مَا فِى قُلُوبِهِمْ فَأَعْرِضْ عَنْهُمْ وَعِظْهُمْ وَقُل لَّهُمْ فِىٓ أَنفُسِهِمْ قَوْلًۢا بَلِيغًا","en":"Those are the ones of whom Allāh knows what is in their hearts, so turn away from them1 but admonish them and speak to them a far-reaching [i.e., effective] word.","tr":"Ola-ika allatheena yaAAlamuAllahu ma fee quloobihim faaAArid AAanhumwaAAithhum waqul lahum fee anfusihim qawlan baleegha","juz":5,"page":88},{"s":4,"a":64,"key":"4:64","ar":"وَمَآ أَرْسَلْنَا مِن رَّسُولٍ إِلَّا لِيُطَاعَ بِإِذْنِ ٱللَّهِ ۚ وَلَوْ أَنَّهُمْ إِذ ظَّلَمُوٓا۟ أَنفُسَهُمْ جَآءُوكَ فَٱسْتَغْفَرُوا۟ ٱللَّهَ وَٱسْتَغْفَرَ لَهُمُ ٱلرَّسُولُ لَوَجَدُوا۟ ٱللَّهَ تَوَّابًا رَّحِيمًا","en":"And We did not send any messenger except to be obeyed by permission of Allāh. And if, when they wronged themselves, they had come to you, [O Muḥammad], and asked forgiveness of Allāh and the Messenger had asked forgiveness for them, they would have found Allāh Accepting of Repentance and Merciful.","tr":"Wama arsalna min rasoolin illaliyutaAAa bi-ithni Allahi walaw annahum iththalamoo anfusahum jaooka fastaghfarooAllaha wastaghfara lahumu arrasoolulawajadoo Allaha tawwaban raheema","juz":5,"page":88},{"s":4,"a":65,"key":"4:65","ar":"فَلَا وَرَبِّكَ لَا يُؤْمِنُونَ حَتَّىٰ يُحَكِّمُوكَ فِيمَا شَجَرَ بَيْنَهُمْ ثُمَّ لَا يَجِدُوا۟ فِىٓ أَنفُسِهِمْ حَرَجًا مِّمَّا قَضَيْتَ وَيُسَلِّمُوا۟ تَسْلِيمًا","en":"But no, by your Lord, they will not [truly] believe until they make you, [O Muḥammad], judge concerning that over which they dispute among themselves and then find within themselves no discomfort from what you have judged and submit in [full, willing] submission.","tr":"Fala warabbika la yu/minoona hattayuhakkimooka feema shajara baynahum thumma layajidoo fee anfusihim harajan mimma qadaytawayusallimoo tasleema","juz":5,"page":88},{"s":4,"a":66,"key":"4:66","ar":"وَلَوْ أَنَّا كَتَبْنَا عَلَيْهِمْ أَنِ ٱقْتُلُوٓا۟ أَنفُسَكُمْ أَوِ ٱخْرُجُوا۟ مِن دِيَـٰرِكُم مَّا فَعَلُوهُ إِلَّا قَلِيلٌ مِّنْهُمْ ۖ وَلَوْ أَنَّهُمْ فَعَلُوا۟ مَا يُوعَظُونَ بِهِۦ لَكَانَ خَيْرًا لَّهُمْ وَأَشَدَّ تَثْبِيتًا","en":"And if We had decreed upon them, \"Kill yourselves\" or \"Leave your homes,\" they would not have done it, except for a few of them. But if they had done what they were instructed, it would have been better for them and a firmer position [for them in faith].","tr":"Walaw anna katabna AAalayhimani oqtuloo anfusakum awi okhrujoo min diyarikum mafaAAaloohu illa qaleelun minhum walaw annahum faAAaloo mayooAAathoona bihi lakana khayran lahumwaashadda tathbeeta","juz":5,"page":89},{"s":4,"a":67,"key":"4:67","ar":"وَإِذًا لَّـَٔاتَيْنَـٰهُم مِّن لَّدُنَّآ أَجْرًا عَظِيمًا","en":"And then We would have given them from Us a great reward.","tr":"Wa-ithan laataynahummin ladunna ajran AAatheema","juz":5,"page":89},{"s":4,"a":68,"key":"4:68","ar":"وَلَهَدَيْنَـٰهُمْ صِرَٰطًا مُّسْتَقِيمًا","en":"And We would have guided them to a straight path.","tr":"Walahadaynahum siratanmustaqeema","juz":5,"page":89},{"s":4,"a":69,"key":"4:69","ar":"وَمَن يُطِعِ ٱللَّهَ وَٱلرَّسُولَ فَأُو۟لَـٰٓئِكَ مَعَ ٱلَّذِينَ أَنْعَمَ ٱللَّهُ عَلَيْهِم مِّنَ ٱلنَّبِيِّـۧنَ وَٱلصِّدِّيقِينَ وَٱلشُّهَدَآءِ وَٱلصَّـٰلِحِينَ ۚ وَحَسُنَ أُو۟لَـٰٓئِكَ رَفِيقًا","en":"And whoever obeys Allāh and the Messenger - those will be with the ones upon whom Allāh has bestowed favor of the prophets, the steadfast affirmers of truth, the martyrs and the righteous. And excellent are those as companions.","tr":"Waman yutiAAi Allaha warrasoolafaola-ika maAAa allatheena anAAama AllahuAAalayhim mina annabiyyeena wassiddeeqeenawashshuhada-i wassaliheenawahasuna ola-ika rafeeqa","juz":5,"page":89},{"s":4,"a":70,"key":"4:70","ar":"ذَٰلِكَ ٱلْفَضْلُ مِنَ ٱللَّهِ ۚ وَكَفَىٰ بِٱللَّهِ عَلِيمًا","en":"That is the bounty from Allāh, and sufficient is Allāh as Knower.","tr":"Thalika alfadlu mina Allahiwakafa billahi AAaleema","juz":5,"page":89},{"s":4,"a":71,"key":"4:71","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ خُذُوا۟ حِذْرَكُمْ فَٱنفِرُوا۟ ثُبَاتٍ أَوِ ٱنفِرُوا۟ جَمِيعًا","en":"O you who have believed, take your precaution and [either] go forth in companies or go forth all together.","tr":"Ya ayyuha allatheena amanookhuthoo hithrakum fanfiroo thubatinawi infiroo jameeAAa","juz":5,"page":89},{"s":4,"a":72,"key":"4:72","ar":"وَإِنَّ مِنكُمْ لَمَن لَّيُبَطِّئَنَّ فَإِنْ أَصَـٰبَتْكُم مُّصِيبَةٌ قَالَ قَدْ أَنْعَمَ ٱللَّهُ عَلَىَّ إِذْ لَمْ أَكُن مَّعَهُمْ شَهِيدًا","en":"And indeed, there is among you he who lingers behind; and if disaster strikes you, he says, \"Allāh has favored me in that I was not present with them.\"","tr":"Wa-inna minkum laman layubatti-annafa-in asabatkum museebatun qala qad anAAamaAllahu AAalayya ith lam akun maAAahum shaheeda","juz":5,"page":89},{"s":4,"a":73,"key":"4:73","ar":"وَلَئِنْ أَصَـٰبَكُمْ فَضْلٌ مِّنَ ٱللَّهِ لَيَقُولَنَّ كَأَن لَّمْ تَكُنۢ بَيْنَكُمْ وَبَيْنَهُۥ مَوَدَّةٌ يَـٰلَيْتَنِى كُنتُ مَعَهُمْ فَأَفُوزَ فَوْزًا عَظِيمًا","en":"But if bounty comes to you from Allāh, he will surely say, as if [i.e., showing that] there had never been between you and him any affection, \"Oh, I wish I had been with them so I could have attained a great attainment.\"1","tr":"Wala-in asabakum fadlun minaAllahi layaqoolanna kaan lam takun baynakum wabaynahumawaddatun ya laytanee kuntu maAAahum faafooza fawzan AAatheema","juz":5,"page":89},{"s":4,"a":74,"key":"4:74","ar":"۞ فَلْيُقَـٰتِلْ فِى سَبِيلِ ٱللَّهِ ٱلَّذِينَ يَشْرُونَ ٱلْحَيَوٰةَ ٱلدُّنْيَا بِٱلْـَٔاخِرَةِ ۚ وَمَن يُقَـٰتِلْ فِى سَبِيلِ ٱللَّهِ فَيُقْتَلْ أَوْ يَغْلِبْ فَسَوْفَ نُؤْتِيهِ أَجْرًا عَظِيمًا","en":"So let those fight in the cause of Allāh who sell the life of this world for the Hereafter. And he who fights in the cause of Allāh and is killed or achieves victory - We will bestow upon him a great reward.","tr":"Falyuqatil fee sabeeli Allahiallatheena yashroona alhayata addunyabil-akhirati waman yuqatil fee sabeeli Allahifayuqtal aw yaghlib fasawfa nu/teehi ajran AAatheema","juz":5,"page":89},{"s":4,"a":75,"key":"4:75","ar":"وَمَا لَكُمْ لَا تُقَـٰتِلُونَ فِى سَبِيلِ ٱللَّهِ وَٱلْمُسْتَضْعَفِينَ مِنَ ٱلرِّجَالِ وَٱلنِّسَآءِ وَٱلْوِلْدَٰنِ ٱلَّذِينَ يَقُولُونَ رَبَّنَآ أَخْرِجْنَا مِنْ هَـٰذِهِ ٱلْقَرْيَةِ ٱلظَّالِمِ أَهْلُهَا وَٱجْعَل لَّنَا مِن لَّدُنكَ وَلِيًّا وَٱجْعَل لَّنَا مِن لَّدُنكَ نَصِيرًا","en":"And what is [the matter] with you that you fight not in the cause of Allāh and [for] the oppressed among men, women, and children who say, \"Our Lord, take us out of this city of oppressive people and appoint for us from Yourself a protector and appoint for us from Yourself a helper\"?","tr":"Wama lakum la tuqatiloonafee sabeeli Allahi walmustadAAafeena mina arrijaliwannisa-i walwildani allatheenayaqooloona rabbana akhrijna min hathihialqaryati aththalimi ahluhawajAAal lana min ladunka waliyyan wajAAallana min ladunka naseera","juz":5,"page":90},{"s":4,"a":76,"key":"4:76","ar":"ٱلَّذِينَ ءَامَنُوا۟ يُقَـٰتِلُونَ فِى سَبِيلِ ٱللَّهِ ۖ وَٱلَّذِينَ كَفَرُوا۟ يُقَـٰتِلُونَ فِى سَبِيلِ ٱلطَّـٰغُوتِ فَقَـٰتِلُوٓا۟ أَوْلِيَآءَ ٱلشَّيْطَـٰنِ ۖ إِنَّ كَيْدَ ٱلشَّيْطَـٰنِ كَانَ ضَعِيفًا","en":"Those who believe fight in the cause of Allāh, and those who disbelieve fight in the cause of ṭāghūt.1 So fight against the allies of Satan. Indeed, the plot of Satan has ever been weak.","tr":"Allatheena amanoo yuqatiloonafee sabeeli Allahi wallatheena kafaroo yuqatiloonafee sabeeli attaghooti faqatiloo awliyaaashshaytani inna kayda ashshaytanikana daAAeefa","juz":5,"page":90},{"s":4,"a":77,"key":"4:77","ar":"أَلَمْ تَرَ إِلَى ٱلَّذِينَ قِيلَ لَهُمْ كُفُّوٓا۟ أَيْدِيَكُمْ وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ فَلَمَّا كُتِبَ عَلَيْهِمُ ٱلْقِتَالُ إِذَا فَرِيقٌ مِّنْهُمْ يَخْشَوْنَ ٱلنَّاسَ كَخَشْيَةِ ٱللَّهِ أَوْ أَشَدَّ خَشْيَةً ۚ وَقَالُوا۟ رَبَّنَا لِمَ كَتَبْتَ عَلَيْنَا ٱلْقِتَالَ لَوْلَآ أَخَّرْتَنَآ إِلَىٰٓ أَجَلٍ قَرِيبٍ ۗ قُلْ مَتَـٰعُ ٱلدُّنْيَا قَلِيلٌ وَٱلْـَٔاخِرَةُ خَيْرٌ لِّمَنِ ٱتَّقَىٰ وَلَا تُظْلَمُونَ فَتِيلًا","en":"Have you not seen those who were told, \"Restrain your hands [from fighting]1 and establish prayer and give zakāh\"? But then when battle was ordained for them, at once a party of them feared men as they fear Allāh or with [even] greater fear. They said, \"Our Lord, why have You decreed upon us fighting? If only You had postponed [it for] us for a short time.\" Say, \"The enjoyment of this world is little, and the Hereafter is better for he who fears Allāh. And injustice will not be done to you, [even] as much as a thread [inside a date seed].\"","tr":"Alam tara ila allatheena qeelalahum kuffoo aydiyakum waaqeemoo assalatawaatoo azzakata falamma kutibaAAalayhimu alqitalu itha fareequn minhum yakhshawnaannasa kakhashyati Allahi aw ashaddakhashyatan waqaloo rabbana lima katabta AAalaynaalqitala lawla akhkhartana ila ajalinqareebin qul mataAAu addunya qaleelun wal-akhiratukhayrun limani ittaqa wala tuthlamoonafateela","juz":5,"page":90},{"s":4,"a":78,"key":"4:78","ar":"أَيْنَمَا تَكُونُوا۟ يُدْرِككُّمُ ٱلْمَوْتُ وَلَوْ كُنتُمْ فِى بُرُوجٍ مُّشَيَّدَةٍ ۗ وَإِن تُصِبْهُمْ حَسَنَةٌ يَقُولُوا۟ هَـٰذِهِۦ مِنْ عِندِ ٱللَّهِ ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌ يَقُولُوا۟ هَـٰذِهِۦ مِنْ عِندِكَ ۚ قُلْ كُلٌّ مِّنْ عِندِ ٱللَّهِ ۖ فَمَالِ هَـٰٓؤُلَآءِ ٱلْقَوْمِ لَا يَكَادُونَ يَفْقَهُونَ حَدِيثًا","en":"Wherever you may be, death will overtake you, even if you should be within towers of lofty construction. But if good comes to them, they say, \"This is from Allāh\"; and if evil befalls them, they say,1 \"This is from you.\" Say, \"All [things] are from Allāh.\" So what is [the matter] with those people that they can hardly understand any statement?","tr":"Aynama takoonoo yudrikkumu almawtuwalaw kuntum fee buroojin mushayyadatin wa-in tusibhum hasanatunyaqooloo hathihi min AAindi Allahi wa-in tusibhumsayyi-atun yaqooloo hathihi min AAindika qul kullun minAAindi Allahi famali haola-i alqawmila yakadoona yafqahoona hadeetha","juz":5,"page":90},{"s":4,"a":79,"key":"4:79","ar":"مَّآ أَصَابَكَ مِنْ حَسَنَةٍ فَمِنَ ٱللَّهِ ۖ وَمَآ أَصَابَكَ مِن سَيِّئَةٍ فَمِن نَّفْسِكَ ۚ وَأَرْسَلْنَـٰكَ لِلنَّاسِ رَسُولًا ۚ وَكَفَىٰ بِٱللَّهِ شَهِيدًا","en":"What comes to you of good is from Allāh, but what comes to you of evil, [O man], is from yourself.1 And We have sent you, [O Muḥammad], to the people as a messenger, and sufficient is Allāh as Witness.2","tr":"Ma asabaka min hasanatinfamina Allahi wama asabaka min sayyi-atinfamin nafsika waarsalnaka linnasi rasoolanwakafa billahi shaheedan","juz":5,"page":90},{"s":4,"a":80,"key":"4:80","ar":"مَّن يُطِعِ ٱلرَّسُولَ فَقَدْ أَطَاعَ ٱللَّهَ ۖ وَمَن تَوَلَّىٰ فَمَآ أَرْسَلْنَـٰكَ عَلَيْهِمْ حَفِيظًا","en":"He who obeys the Messenger has obeyed Allāh; but those who turn away - We have not sent you over them as a guardian.","tr":"Man yutiAAi arrasoola faqad ataAAaAllaha waman tawalla fama arsalnakaAAalayhim hafeetha","juz":5,"page":91},{"s":4,"a":81,"key":"4:81","ar":"وَيَقُولُونَ طَاعَةٌ فَإِذَا بَرَزُوا۟ مِنْ عِندِكَ بَيَّتَ طَآئِفَةٌ مِّنْهُمْ غَيْرَ ٱلَّذِى تَقُولُ ۖ وَٱللَّهُ يَكْتُبُ مَا يُبَيِّتُونَ ۖ فَأَعْرِضْ عَنْهُمْ وَتَوَكَّلْ عَلَى ٱللَّهِ ۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًا","en":"And they say, \"[We pledge] obedience.\" But when they leave you, a group of them spend the night determining to do other than what you say. But Allāh records what they plan by night. So leave them alone and rely upon Allāh. And sufficient is Allāh as Disposer of affairs.","tr":"Wayaqooloona taAAatun fa-ithabarazoo min AAindika bayyata ta-ifatun minhum ghayra allatheetaqoolu wallahu yaktubu ma yubayyitoonafaaAArid AAanhum watawakkal AAala Allahiwakafa billahi wakeela","juz":5,"page":91},{"s":4,"a":82,"key":"4:82","ar":"أَفَلَا يَتَدَبَّرُونَ ٱلْقُرْءَانَ ۚ وَلَوْ كَانَ مِنْ عِندِ غَيْرِ ٱللَّهِ لَوَجَدُوا۟ فِيهِ ٱخْتِلَـٰفًا كَثِيرًا","en":"Then do they not reflect upon the Qur’ān?1 If it had been from [any] other than Allāh, they would have found within it much contradiction.","tr":"Afala yatadabbaroona alqur-anawalaw kana min AAindi ghayri Allahi lawajadoo feehiikhtilafan katheera","juz":5,"page":91},{"s":4,"a":83,"key":"4:83","ar":"وَإِذَا جَآءَهُمْ أَمْرٌ مِّنَ ٱلْأَمْنِ أَوِ ٱلْخَوْفِ أَذَاعُوا۟ بِهِۦ ۖ وَلَوْ رَدُّوهُ إِلَى ٱلرَّسُولِ وَإِلَىٰٓ أُو۟لِى ٱلْأَمْرِ مِنْهُمْ لَعَلِمَهُ ٱلَّذِينَ يَسْتَنۢبِطُونَهُۥ مِنْهُمْ ۗ وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ لَٱتَّبَعْتُمُ ٱلشَّيْطَـٰنَ إِلَّا قَلِيلًا","en":"And when there comes to them something [i.e., information] about [public] security or fear, they spread it around. But if they had referred it back to the Messenger or to those of authority among them, then the ones who [can] draw correct conclusions from it would have known about it. And if not for the favor of Allāh upon you and His mercy, you would have followed Satan, except for a few.","tr":"Wa-itha jaahum amrun minaal-amni awi alkhawfi athaAAoo bihi walaw raddoohu ilaarrasooli wa-ila olee al-amri minhum laAAalimahuallatheena yastanbitoonahu minhum walawla fadluAllahi AAalaykum warahmatuhu lattabaAAtumuashshaytana illa qaleela","juz":5,"page":91},{"s":4,"a":84,"key":"4:84","ar":"فَقَـٰتِلْ فِى سَبِيلِ ٱللَّهِ لَا تُكَلَّفُ إِلَّا نَفْسَكَ ۚ وَحَرِّضِ ٱلْمُؤْمِنِينَ ۖ عَسَى ٱللَّهُ أَن يَكُفَّ بَأْسَ ٱلَّذِينَ كَفَرُوا۟ ۚ وَٱللَّهُ أَشَدُّ بَأْسًا وَأَشَدُّ تَنكِيلًا","en":"So fight, [O Muḥammad], in the cause of Allāh; you are not held responsible except for yourself. And encourage the believers [to join you] that perhaps Allāh will restrain the [military] might of those who disbelieve. And Allāh is greater in might and stronger in [exemplary] punishment.1","tr":"Faqatil fee sabeeli Allahi latukallafu illa nafsaka waharridialmu/mineena AAasa Allahu an yakuffa ba/sa allatheenakafaroo wallahu ashaddu ba/san waashaddu tankeela","juz":5,"page":91},{"s":4,"a":85,"key":"4:85","ar":"مَّن يَشْفَعْ شَفَـٰعَةً حَسَنَةً يَكُن لَّهُۥ نَصِيبٌ مِّنْهَا ۖ وَمَن يَشْفَعْ شَفَـٰعَةً سَيِّئَةً يَكُن لَّهُۥ كِفْلٌ مِّنْهَا ۗ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ مُّقِيتًا","en":"Whoever intercedes for a good cause will have a share [i.e., reward] therefrom; and whoever intercedes for an evil cause will have a portion [i.e., burden] therefrom. And ever is Allāh, over all things, a Keeper.1","tr":"Man yashfaAA shafaAAatan hasanatanyakun lahu naseebun minha waman yashfaAA shafaAAatansayyi-atan yakun lahu kiflun minha wakana AllahuAAala kulli shay-in muqeeta","juz":5,"page":91},{"s":4,"a":86,"key":"4:86","ar":"وَإِذَا حُيِّيتُم بِتَحِيَّةٍ فَحَيُّوا۟ بِأَحْسَنَ مِنْهَآ أَوْ رُدُّوهَآ ۗ إِنَّ ٱللَّهَ كَانَ عَلَىٰ كُلِّ شَىْءٍ حَسِيبًا","en":"And when you are greeted with a greeting, greet [in return] with one better than it or [at least] return it [in a like manner]. Indeed Allāh is ever, over all things, an Accountant.","tr":"Wa-itha huyyeetum bitahiyyatinfahayyoo bi-ahsana minha aw ruddoohainna Allaha kana AAala kulli shay-in haseeba","juz":5,"page":91},{"s":4,"a":87,"key":"4:87","ar":"ٱللَّهُ لَآ إِلَـٰهَ إِلَّا هُوَ ۚ لَيَجْمَعَنَّكُمْ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ لَا رَيْبَ فِيهِ ۗ وَمَنْ أَصْدَقُ مِنَ ٱللَّهِ حَدِيثًا","en":"Allāh - there is no deity except Him. He will surely assemble you for [account on] the Day of Resurrection, about which there is no doubt. And who is more truthful than Allāh in statement.","tr":"Allahu la ilaha illahuwa layajmaAAannakum ila yawmi alqiyamati larayba feehi waman asdaqu mina Allahi hadeetha","juz":5,"page":92},{"s":4,"a":88,"key":"4:88","ar":"۞ فَمَا لَكُمْ فِى ٱلْمُنَـٰفِقِينَ فِئَتَيْنِ وَٱللَّهُ أَرْكَسَهُم بِمَا كَسَبُوٓا۟ ۚ أَتُرِيدُونَ أَن تَهْدُوا۟ مَنْ أَضَلَّ ٱللَّهُ ۖ وَمَن يُضْلِلِ ٱللَّهُ فَلَن تَجِدَ لَهُۥ سَبِيلًا","en":"What is [the matter] with you [that you are] two groups concerning the hypocrites,1 while Allāh has made them fall back [into error and disbelief] for what they earned.2 Do you wish to guide those whom Allāh has sent astray? And he whom Allāh sends astray - never will you find for him a way [of guidance].3","tr":"Fama lakum fee almunafiqeenafi-atayni wallahu arkasahum bima kasabooatureedoona an tahdoo man adalla Allahu waman yudliliAllahu falan tajida lahu sabeela","juz":5,"page":92},{"s":4,"a":89,"key":"4:89","ar":"وَدُّوا۟ لَوْ تَكْفُرُونَ كَمَا كَفَرُوا۟ فَتَكُونُونَ سَوَآءً ۖ فَلَا تَتَّخِذُوا۟ مِنْهُمْ أَوْلِيَآءَ حَتَّىٰ يُهَاجِرُوا۟ فِى سَبِيلِ ٱللَّهِ ۚ فَإِن تَوَلَّوْا۟ فَخُذُوهُمْ وَٱقْتُلُوهُمْ حَيْثُ وَجَدتُّمُوهُمْ ۖ وَلَا تَتَّخِذُوا۟ مِنْهُمْ وَلِيًّا وَلَا نَصِيرًا","en":"They wish you would disbelieve as they disbelieved so you would be alike. So do not take from among them allies until they emigrate for the cause of Allāh. But if they turn away [i.e., refuse], then seize them and kill them [for their betrayal] wherever you find them and take not from among them any ally or helper,","tr":"Waddoo law takfuroona kama kafaroofatakoonoona sawaan fala tattakhithoo minhumawliyaa hatta yuhajiroo fee sabeeliAllahi fa-in tawallaw fakhuthoohum waqtuloohumhaythu wajadtumoohum wala tattakhithoominhum waliyyan wala naseera","juz":5,"page":92},{"s":4,"a":90,"key":"4:90","ar":"إِلَّا ٱلَّذِينَ يَصِلُونَ إِلَىٰ قَوْمٍۭ بَيْنَكُمْ وَبَيْنَهُم مِّيثَـٰقٌ أَوْ جَآءُوكُمْ حَصِرَتْ صُدُورُهُمْ أَن يُقَـٰتِلُوكُمْ أَوْ يُقَـٰتِلُوا۟ قَوْمَهُمْ ۚ وَلَوْ شَآءَ ٱللَّهُ لَسَلَّطَهُمْ عَلَيْكُمْ فَلَقَـٰتَلُوكُمْ ۚ فَإِنِ ٱعْتَزَلُوكُمْ فَلَمْ يُقَـٰتِلُوكُمْ وَأَلْقَوْا۟ إِلَيْكُمُ ٱلسَّلَمَ فَمَا جَعَلَ ٱللَّهُ لَكُمْ عَلَيْهِمْ سَبِيلًا","en":"Except for those who take refuge with a people between yourselves and whom is a treaty or those who come to you, their hearts strained at [the prospect of] fighting you or fighting their own people. And if Allāh had willed, He could have given them power over you, and they would have fought you. So if they remove themselves from you and do not fight you and offer you peace, then Allāh has not made for you a cause [for fighting] against them.","tr":"Illa allatheena yasiloonaila qawmin baynakum wabaynahum meethaqun aw jaookumhasirat sudooruhum an yuqatilookum awyuqatiloo qawmahum walaw shaa Allahu lasallatahumAAalaykum falaqatalookum fa-ini iAAtazalookum falam yuqatilookumwaalqaw ilaykumu assalama fama jaAAala Allahulakum AAalayhim sabeela","juz":5,"page":92},{"s":4,"a":91,"key":"4:91","ar":"سَتَجِدُونَ ءَاخَرِينَ يُرِيدُونَ أَن يَأْمَنُوكُمْ وَيَأْمَنُوا۟ قَوْمَهُمْ كُلَّ مَا رُدُّوٓا۟ إِلَى ٱلْفِتْنَةِ أُرْكِسُوا۟ فِيهَا ۚ فَإِن لَّمْ يَعْتَزِلُوكُمْ وَيُلْقُوٓا۟ إِلَيْكُمُ ٱلسَّلَمَ وَيَكُفُّوٓا۟ أَيْدِيَهُمْ فَخُذُوهُمْ وَٱقْتُلُوهُمْ حَيْثُ ثَقِفْتُمُوهُمْ ۚ وَأُو۟لَـٰٓئِكُمْ جَعَلْنَا لَكُمْ عَلَيْهِمْ سُلْطَـٰنًا مُّبِينًا","en":"You will find others who wish to obtain security from you and [to] obtain security from their people. Every time they are returned to [the influence of] disbelief, they fall back into it. So if they do not withdraw from you or offer you peace or restrain their hands, then seize them and kill them wherever you overtake them. And those - We have made for you against them a clear authorization.","tr":"Satajidoona akhareena yureedoona anya/manookum waya/manoo qawmahum kulla ma ruddoo ilaalfitnati orkisoo feeha fa-in lam yaAAtazilookum wayulqooilaykumu assalama wayakuffoo aydiyahum fakhuthoohumwaqtuloohum haythu thaqiftumoohum waola-ikumjaAAalna lakum AAalayhim sultanan mubeena","juz":5,"page":92},{"s":4,"a":92,"key":"4:92","ar":"وَمَا كَانَ لِمُؤْمِنٍ أَن يَقْتُلَ مُؤْمِنًا إِلَّا خَطَـًٔا ۚ وَمَن قَتَلَ مُؤْمِنًا خَطَـًٔا فَتَحْرِيرُ رَقَبَةٍ مُّؤْمِنَةٍ وَدِيَةٌ مُّسَلَّمَةٌ إِلَىٰٓ أَهْلِهِۦٓ إِلَّآ أَن يَصَّدَّقُوا۟ ۚ فَإِن كَانَ مِن قَوْمٍ عَدُوٍّ لَّكُمْ وَهُوَ مُؤْمِنٌ فَتَحْرِيرُ رَقَبَةٍ مُّؤْمِنَةٍ ۖ وَإِن كَانَ مِن قَوْمٍۭ بَيْنَكُمْ وَبَيْنَهُم مِّيثَـٰقٌ فَدِيَةٌ مُّسَلَّمَةٌ إِلَىٰٓ أَهْلِهِۦ وَتَحْرِيرُ رَقَبَةٍ مُّؤْمِنَةٍ ۖ فَمَن لَّمْ يَجِدْ فَصِيَامُ شَهْرَيْنِ مُتَتَابِعَيْنِ تَوْبَةً مِّنَ ٱللَّهِ ۗ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًا","en":"And never is it for a believer to kill a believer except by mistake. And whoever kills a believer by mistake - then the freeing of a believing slave and a compensation payment [diyah] presented to his [i.e., the deceased's] family [is required], unless they give [up their right as] charity. But if he [i.e., the deceased] was from a people at war with you and he was a believer - then [only] the freeing of a believing slave; and if he was from a people with whom you have a treaty - then a compensation payment presented to his family and the freeing of a believing slave. And whoever does not find [one or cannot afford to buy one] - then [instead], a fast for two months consecutively,1 [seeking] acceptance of repentance from Allāh.2 And Allāh is ever Knowing and Wise.","tr":"Wama kana limu/minin anyaqtula mu/minan illa khataan waman qatala mu/minankhataan fatahreeru raqabatin mu/minatin wadiyatunmusallamatun ila ahlihi illa an yassaddaqoofa-in kana min qawmin AAaduwwin lakum wahuwa mu/minun fatahreeruraqabatin mu/minatin wa-in kana min qawmin baynakumwabaynahum meethaqun fadiyatun musallamatun ilaahlihi watahreeru raqabatin mu/minatin faman lam yajid fasiyamushahrayni mutatabiAAayni tawbatan mina Allahi wakanaAllahu AAaleeman hakeema","juz":5,"page":93},{"s":4,"a":93,"key":"4:93","ar":"وَمَن يَقْتُلْ مُؤْمِنًا مُّتَعَمِّدًا فَجَزَآؤُهُۥ جَهَنَّمُ خَـٰلِدًا فِيهَا وَغَضِبَ ٱللَّهُ عَلَيْهِ وَلَعَنَهُۥ وَأَعَدَّ لَهُۥ عَذَابًا عَظِيمًا","en":"But whoever kills a believer intentionally - his recompense is Hell, wherein he will abide eternally, and Allāh has become angry with him and has cursed him and has prepared for him a great punishment.","tr":"Waman yaqtul mu/minan mutaAAammidan fajazaohujahannamu khalidan feeha waghadiba AllahuAAalayhi walaAAanahu waaAAadda lahu AAathaban AAatheema","juz":5,"page":93},{"s":4,"a":94,"key":"4:94","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا ضَرَبْتُمْ فِى سَبِيلِ ٱللَّهِ فَتَبَيَّنُوا۟ وَلَا تَقُولُوا۟ لِمَنْ أَلْقَىٰٓ إِلَيْكُمُ ٱلسَّلَـٰمَ لَسْتَ مُؤْمِنًا تَبْتَغُونَ عَرَضَ ٱلْحَيَوٰةِ ٱلدُّنْيَا فَعِندَ ٱللَّهِ مَغَانِمُ كَثِيرَةٌ ۚ كَذَٰلِكَ كُنتُم مِّن قَبْلُ فَمَنَّ ٱللَّهُ عَلَيْكُمْ فَتَبَيَّنُوٓا۟ ۚ إِنَّ ٱللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًا","en":"O you who have believed, when you go forth [to fight] in the cause of Allāh, investigate; and do not say to one who gives you [a greeting of] peace, \"You are not a believer,\"1 aspiring for the goods of worldly life; for with Allāh are many acquisitions. You [yourselves] were like that before; then Allāh conferred His favor [i.e., guidance] upon you, so investigate. Indeed Allāh is ever, of what you do, Aware.","tr":"Ya ayyuha allatheena amanooitha darabtum fee sabeeli Allahifatabayyanoo wala taqooloo liman alqa ilaykumu assalamalasta mu/minan tabtaghoona AAarada alhayatiaddunya faAAinda Allahi maghanimukatheeratun kathalika kuntum min qablu famanna AllahuAAalaykum fatabayyanoo inna Allaha kana bimataAAmaloona khabeera","juz":5,"page":93},{"s":4,"a":95,"key":"4:95","ar":"لَّا يَسْتَوِى ٱلْقَـٰعِدُونَ مِنَ ٱلْمُؤْمِنِينَ غَيْرُ أُو۟لِى ٱلضَّرَرِ وَٱلْمُجَـٰهِدُونَ فِى سَبِيلِ ٱللَّهِ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ ۚ فَضَّلَ ٱللَّهُ ٱلْمُجَـٰهِدِينَ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ عَلَى ٱلْقَـٰعِدِينَ دَرَجَةً ۚ وَكُلًّا وَعَدَ ٱللَّهُ ٱلْحُسْنَىٰ ۚ وَفَضَّلَ ٱللَّهُ ٱلْمُجَـٰهِدِينَ عَلَى ٱلْقَـٰعِدِينَ أَجْرًا عَظِيمًا","en":"Not equal are those believers remaining [at home] - other than the disabled - and the mujāhideen, [who strive and fight] in the cause of Allāh with their wealth and their lives. Allāh has preferred the mujāhideen through their wealth and their lives over those who remain [behind], by degrees. And to all [i.e., both] Allāh has promised the best [reward]. But Allāh has preferred the mujāhideen over those who remain [behind] with a great reward -","tr":"La yastawee alqaAAidoona minaalmu/mineena ghayru olee addarari walmujahidoonafee sabeeli Allahi bi-amwalihim waanfusihim faddalaAllahu almujahideena bi-amwalihimwaanfusihim AAala alqaAAideena darajatan wakullanwaAAada Allahu alhusna wafaddala Allahualmujahideena AAala alqaAAideena ajran AAatheema","juz":5,"page":94},{"s":4,"a":96,"key":"4:96","ar":"دَرَجَـٰتٍ مِّنْهُ وَمَغْفِرَةً وَرَحْمَةً ۚ وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًا","en":"Degrees [of high position] from Him and forgiveness and mercy. And Allāh is ever Forgiving and Merciful.","tr":"Darajatin minhu wamaghfiratan warahmatanwakana Allahu ghafooran raheema","juz":5,"page":94},{"s":4,"a":97,"key":"4:97","ar":"إِنَّ ٱلَّذِينَ تَوَفَّىٰهُمُ ٱلْمَلَـٰٓئِكَةُ ظَالِمِىٓ أَنفُسِهِمْ قَالُوا۟ فِيمَ كُنتُمْ ۖ قَالُوا۟ كُنَّا مُسْتَضْعَفِينَ فِى ٱلْأَرْضِ ۚ قَالُوٓا۟ أَلَمْ تَكُنْ أَرْضُ ٱللَّهِ وَٰسِعَةً فَتُهَاجِرُوا۟ فِيهَا ۚ فَأُو۟لَـٰٓئِكَ مَأْوَىٰهُمْ جَهَنَّمُ ۖ وَسَآءَتْ مَصِيرًا","en":"Indeed, those whom the angels take [in death] while wronging themselves1 - [the angels] will say, \"In what [condition] were you?\" They will say, \"We were oppressed in the land.\" They [the angels] will say, \"Was not the earth of Allāh spacious [enough] for you to emigrate therein?\" For those, their refuge is Hell - and evil it is as a destination.","tr":"Inna allatheena tawaffahumualmala-ikatu thalimee anfusihim qaloofeema kuntum qaloo kunna mustadAAafeena feeal-ardi qaloo alam takun ardu AllahiwasiAAatan fatuhajiroo feeha faola-ikama/wahum jahannamu wasaat maseera","juz":5,"page":94},{"s":4,"a":98,"key":"4:98","ar":"إِلَّا ٱلْمُسْتَضْعَفِينَ مِنَ ٱلرِّجَالِ وَٱلنِّسَآءِ وَٱلْوِلْدَٰنِ لَا يَسْتَطِيعُونَ حِيلَةً وَلَا يَهْتَدُونَ سَبِيلًا","en":"Except for the oppressed among men, women, and children who cannot devise a plan nor are they directed to a way1 -","tr":"Illa almustadAAafeena mina arrijaliwannisa-i walwildani layastateeAAoona heelatan wala yahtadoonasabeela","juz":5,"page":94},{"s":4,"a":99,"key":"4:99","ar":"فَأُو۟لَـٰٓئِكَ عَسَى ٱللَّهُ أَن يَعْفُوَ عَنْهُمْ ۚ وَكَانَ ٱللَّهُ عَفُوًّا غَفُورًا","en":"For those it is expected that Allāh will pardon them, and Allāh is ever Pardoning1 and Forgiving.","tr":"Faola-ika AAasa Allahuan yaAAfuwa AAanhum wakana Allahu AAafuwwan ghafoora","juz":5,"page":94},{"s":4,"a":100,"key":"4:100","ar":"۞ وَمَن يُهَاجِرْ فِى سَبِيلِ ٱللَّهِ يَجِدْ فِى ٱلْأَرْضِ مُرَٰغَمًا كَثِيرًا وَسَعَةً ۚ وَمَن يَخْرُجْ مِنۢ بَيْتِهِۦ مُهَاجِرًا إِلَى ٱللَّهِ وَرَسُولِهِۦ ثُمَّ يُدْرِكْهُ ٱلْمَوْتُ فَقَدْ وَقَعَ أَجْرُهُۥ عَلَى ٱللَّهِ ۗ وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًا","en":"And whoever emigrates for the cause of Allāh will find on the earth many [alternative] locations and abundance. And whoever leaves his home as an emigrant to Allāh and His Messenger and then death overtakes him - his reward has already become incumbent upon Allāh. And Allāh is ever Forgiving and Merciful.","tr":"Waman yuhajir fee sabeeli Allahiyajid fee al-ardi muraghaman katheeran wasaAAatanwaman yakhruj min baytihi muhajiran ila Allahiwarasoolihi thumma yudrik-hu almawtu faqad waqaAAa ajruhu AAalaAllahi wakana Allahu ghafooran raheema","juz":5,"page":94},{"s":4,"a":101,"key":"4:101","ar":"وَإِذَا ضَرَبْتُمْ فِى ٱلْأَرْضِ فَلَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَقْصُرُوا۟ مِنَ ٱلصَّلَوٰةِ إِنْ خِفْتُمْ أَن يَفْتِنَكُمُ ٱلَّذِينَ كَفَرُوٓا۟ ۚ إِنَّ ٱلْكَـٰفِرِينَ كَانُوا۟ لَكُمْ عَدُوًّا مُّبِينًا","en":"And when you travel throughout the land, there is no blame upon you for shortening the prayer,1 [especially] if you fear that those who disbelieve may disrupt [or attack] you.2 Indeed, the disbelievers are ever to you a clear enemy.","tr":"Wa-itha darabtum fee al-ardifalaysa AAalaykum junahun an taqsuroo mina assalatiin khiftum an yaftinakumu allatheena kafaroo inna alkafireenakanoo lakum AAaduwwan mubeena","juz":5,"page":94},{"s":4,"a":102,"key":"4:102","ar":"وَإِذَا كُنتَ فِيهِمْ فَأَقَمْتَ لَهُمُ ٱلصَّلَوٰةَ فَلْتَقُمْ طَآئِفَةٌ مِّنْهُم مَّعَكَ وَلْيَأْخُذُوٓا۟ أَسْلِحَتَهُمْ فَإِذَا سَجَدُوا۟ فَلْيَكُونُوا۟ مِن وَرَآئِكُمْ وَلْتَأْتِ طَآئِفَةٌ أُخْرَىٰ لَمْ يُصَلُّوا۟ فَلْيُصَلُّوا۟ مَعَكَ وَلْيَأْخُذُوا۟ حِذْرَهُمْ وَأَسْلِحَتَهُمْ ۗ وَدَّ ٱلَّذِينَ كَفَرُوا۟ لَوْ تَغْفُلُونَ عَنْ أَسْلِحَتِكُمْ وَأَمْتِعَتِكُمْ فَيَمِيلُونَ عَلَيْكُم مَّيْلَةً وَٰحِدَةً ۚ وَلَا جُنَاحَ عَلَيْكُمْ إِن كَانَ بِكُمْ أَذًى مِّن مَّطَرٍ أَوْ كُنتُم مَّرْضَىٰٓ أَن تَضَعُوٓا۟ أَسْلِحَتَكُمْ ۖ وَخُذُوا۟ حِذْرَكُمْ ۗ إِنَّ ٱللَّهَ أَعَدَّ لِلْكَـٰفِرِينَ عَذَابًا مُّهِينًا","en":"And when you [i.e., the commander of an army] are among them and lead them in prayer,1 let a group of them stand [in prayer] with you and let them carry their arms. And when they have prostrated, let them be [in position] behind you and have the other group come forward which has not [yet] prayed and let them pray with you, taking precaution and carrying their arms. Those who disbelieve wish that you would neglect your weapons and your baggage so they could come down upon you in one [single] attack. But there is no blame upon you, if you are troubled by rain or are ill, for putting down your arms, but take precaution. Indeed, Allāh has prepared for the disbelievers a humiliating punishment.","tr":"Wa-itha kunta feehim faaqamta lahumuassalata faltaqum ta-ifatun minhummaAAaka walya/khuthoo aslihatahum fa-ithasajadoo falyakoonoo min wara-ikum walta/ti ta-ifatunokhra lam yusalloo falyusalloo maAAakawalya/khuthoo hithrahum waaslihatahumwadda allatheena kafaroo law taghfuloona AAan aslihatikumwaamtiAAatikum fayameeloona AAalaykum maylatan wahidatanwala junaha AAalaykum in kana bikum athanmin matarin aw kuntum marda an tadaAAoo aslihatakumwakhuthoo hithrakum inna AllahaaAAadda lilkafireena AAathaban muheena","juz":5,"page":95},{"s":4,"a":103,"key":"4:103","ar":"فَإِذَا قَضَيْتُمُ ٱلصَّلَوٰةَ فَٱذْكُرُوا۟ ٱللَّهَ قِيَـٰمًا وَقُعُودًا وَعَلَىٰ جُنُوبِكُمْ ۚ فَإِذَا ٱطْمَأْنَنتُمْ فَأَقِيمُوا۟ ٱلصَّلَوٰةَ ۚ إِنَّ ٱلصَّلَوٰةَ كَانَتْ عَلَى ٱلْمُؤْمِنِينَ كِتَـٰبًا مَّوْقُوتًا","en":"And when you have completed the prayer, remember Allāh standing, sitting, or [lying] on your sides. But when you become secure, re-establish [regular] prayer. Indeed, prayer has been decreed upon the believers a decree of specified times.","tr":"Fa-itha qadaytumu assalatafathkuroo Allaha qiyaman waquAAoodanwaAAala junoobikum fa-itha itma/nantumfaaqeemoo assalata inna assalatakanat AAala almu/mineena kitaban mawqoota","juz":5,"page":95},{"s":4,"a":104,"key":"4:104","ar":"وَلَا تَهِنُوا۟ فِى ٱبْتِغَآءِ ٱلْقَوْمِ ۖ إِن تَكُونُوا۟ تَأْلَمُونَ فَإِنَّهُمْ يَأْلَمُونَ كَمَا تَأْلَمُونَ ۖ وَتَرْجُونَ مِنَ ٱللَّهِ مَا لَا يَرْجُونَ ۗ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًا","en":"And do not weaken in pursuit of the enemy. If you should be suffering - so are they suffering as you are suffering, but you expect from Allāh that which they expect not. And Allāh is ever Knowing and Wise.","tr":"Wala tahinoo fee ibtigha-ialqawmi in takoonoo ta/lamoona fa-innahum ya/lamoona kamata/lamoona watarjoona mina Allahi ma layarjoona wakana Allahu AAaleeman hakeema","juz":5,"page":95},{"s":4,"a":105,"key":"4:105","ar":"إِنَّآ أَنزَلْنَآ إِلَيْكَ ٱلْكِتَـٰبَ بِٱلْحَقِّ لِتَحْكُمَ بَيْنَ ٱلنَّاسِ بِمَآ أَرَىٰكَ ٱللَّهُ ۚ وَلَا تَكُن لِّلْخَآئِنِينَ خَصِيمًا","en":"Indeed, We have revealed to you, [O Muḥammad], the Book in truth so you may judge between the people by that which Allāh has shown you. And do not be for the deceitful an advocate.","tr":"Inna anzalna ilayka alkitababilhaqqi litahkuma bayna annasibima araka Allahu wala takun lilkha-ineenakhaseema","juz":5,"page":95},{"s":4,"a":106,"key":"4:106","ar":"وَٱسْتَغْفِرِ ٱللَّهَ ۖ إِنَّ ٱللَّهَ كَانَ غَفُورًا رَّحِيمًا","en":"And seek forgiveness of Allāh. Indeed, Allāh is ever Forgiving and Merciful.","tr":"Wastaghfiri Allaha inna Allahakana ghafooran raheema","juz":5,"page":96},{"s":4,"a":107,"key":"4:107","ar":"وَلَا تُجَـٰدِلْ عَنِ ٱلَّذِينَ يَخْتَانُونَ أَنفُسَهُمْ ۚ إِنَّ ٱللَّهَ لَا يُحِبُّ مَن كَانَ خَوَّانًا أَثِيمًا","en":"And do not argue on behalf of those who deceive themselves. Indeed, Allāh loves not one who is a habitually sinful deceiver.","tr":"Wala tujadil AAani allatheenayakhtanoona anfusahum inna Allaha la yuhibbuman kana khawwanan atheema","juz":5,"page":96},{"s":4,"a":108,"key":"4:108","ar":"يَسْتَخْفُونَ مِنَ ٱلنَّاسِ وَلَا يَسْتَخْفُونَ مِنَ ٱللَّهِ وَهُوَ مَعَهُمْ إِذْ يُبَيِّتُونَ مَا لَا يَرْضَىٰ مِنَ ٱلْقَوْلِ ۚ وَكَانَ ٱللَّهُ بِمَا يَعْمَلُونَ مُحِيطًا","en":"They conceal [their evil intentions and deeds] from the people, but they cannot conceal [them] from Allāh, and He is with them [in His knowledge] when they spend the night in such as He does not accept of speech. And ever is Allāh, of what they do, encompassing.","tr":"Yastakhfoona mina annasi walayastakhfoona mina Allahi wahuwa maAAahum ithyubayyitoona ma la yarda mina alqawli wakanaAllahu bima yaAAmaloona muheeta","juz":5,"page":96},{"s":4,"a":109,"key":"4:109","ar":"هَـٰٓأَنتُمْ هَـٰٓؤُلَآءِ جَـٰدَلْتُمْ عَنْهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا فَمَن يُجَـٰدِلُ ٱللَّهَ عَنْهُمْ يَوْمَ ٱلْقِيَـٰمَةِ أَم مَّن يَكُونُ عَلَيْهِمْ وَكِيلًا","en":"Here you are - those who argue on their behalf in [this] worldly life - but who will argue with Allāh for them on the Day of Resurrection, or who will [then] be their representative?","tr":"Haantum haola-i jadaltumAAanhum fee alhayati addunya famanyujadilu Allaha AAanhum yawma alqiyamati amman yakoonu AAalayhim wakeela","juz":5,"page":96},{"s":4,"a":110,"key":"4:110","ar":"وَمَن يَعْمَلْ سُوٓءًا أَوْ يَظْلِمْ نَفْسَهُۥ ثُمَّ يَسْتَغْفِرِ ٱللَّهَ يَجِدِ ٱللَّهَ غَفُورًا رَّحِيمًا","en":"And whoever does a wrong or wrongs himself but then seeks forgiveness of Allāh will find Allāh Forgiving and Merciful.","tr":"Waman yaAAmal soo-an aw yathlimnafsahu thumma yastaghfiri Allaha yajidi Allahaghafooran raheema","juz":5,"page":96},{"s":4,"a":111,"key":"4:111","ar":"وَمَن يَكْسِبْ إِثْمًا فَإِنَّمَا يَكْسِبُهُۥ عَلَىٰ نَفْسِهِۦ ۚ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًا","en":"And whoever earns [i.e., commits] a sin only earns it against himself. And Allāh is ever Knowing and Wise.","tr":"Waman yaksib ithman fa-innamayaksibuhu AAala nafsihi wakana AllahuAAaleeman hakeema","juz":5,"page":96},{"s":4,"a":112,"key":"4:112","ar":"وَمَن يَكْسِبْ خَطِيٓـَٔةً أَوْ إِثْمًا ثُمَّ يَرْمِ بِهِۦ بَرِيٓـًٔا فَقَدِ ٱحْتَمَلَ بُهْتَـٰنًا وَإِثْمًا مُّبِينًا","en":"But whoever earns an offense or a sin and then blames it on an innocent [person] has taken upon himself a slander and manifest sin.","tr":"Waman yaksib khatee-atan aw ithmanthumma yarmi bihi baree-an faqadi ihtamala buhtananwa-ithman mubeena","juz":5,"page":96},{"s":4,"a":113,"key":"4:113","ar":"وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكَ وَرَحْمَتُهُۥ لَهَمَّت طَّآئِفَةٌ مِّنْهُمْ أَن يُضِلُّوكَ وَمَا يُضِلُّونَ إِلَّآ أَنفُسَهُمْ ۖ وَمَا يَضُرُّونَكَ مِن شَىْءٍ ۚ وَأَنزَلَ ٱللَّهُ عَلَيْكَ ٱلْكِتَـٰبَ وَٱلْحِكْمَةَ وَعَلَّمَكَ مَا لَمْ تَكُن تَعْلَمُ ۚ وَكَانَ فَضْلُ ٱللَّهِ عَلَيْكَ عَظِيمًا","en":"And if it was not for the favor of Allāh upon you, [O Muḥammad], and His mercy, a group of them would have determined to mislead you. But they do not mislead except themselves, and they will not harm you at all. And Allāh has revealed to you the Book and wisdom and has taught you that which you did not know. And ever has the favor of Allāh upon you been great.","tr":"Walawla fadlu AllahiAAalayka warahmatuhu lahammat ta-ifatun minhum anyudillooka wama yudilloona illaanfusahum wama yadurroonaka min shay-in waanzalaAllahu AAalayka alkitaba walhikmatawaAAallamaka ma lam takun taAAlamu wakana fadluAllahi AAalayka AAatheema","juz":5,"page":96},{"s":4,"a":114,"key":"4:114","ar":"۞ لَّا خَيْرَ فِى كَثِيرٍ مِّن نَّجْوَىٰهُمْ إِلَّا مَنْ أَمَرَ بِصَدَقَةٍ أَوْ مَعْرُوفٍ أَوْ إِصْلَـٰحٍۭ بَيْنَ ٱلنَّاسِ ۚ وَمَن يَفْعَلْ ذَٰلِكَ ٱبْتِغَآءَ مَرْضَاتِ ٱللَّهِ فَسَوْفَ نُؤْتِيهِ أَجْرًا عَظِيمًا","en":"No good is there in much of their private conversation, except for those who enjoin charity or that which is right or conciliation between people. And whoever does that seeking means to the approval of Allāh - then We are going to give him a great reward.","tr":"La khayra fee katheerin min najwahumilla man amara bisadaqatin aw maAAroofin aw islahinbayna annasi waman yafAAal thalika ibtighaamardati Allahi fasawfa nu/teehi ajran AAatheema","juz":5,"page":97},{"s":4,"a":115,"key":"4:115","ar":"وَمَن يُشَاقِقِ ٱلرَّسُولَ مِنۢ بَعْدِ مَا تَبَيَّنَ لَهُ ٱلْهُدَىٰ وَيَتَّبِعْ غَيْرَ سَبِيلِ ٱلْمُؤْمِنِينَ نُوَلِّهِۦ مَا تَوَلَّىٰ وَنُصْلِهِۦ جَهَنَّمَ ۖ وَسَآءَتْ مَصِيرًا","en":"And whoever opposes the Messenger after guidance has become clear to him and follows other than the way of the believers - We will give him what he has taken1 and drive him into Hell, and evil it is as a destination.","tr":"Waman yushaqiqi arrasoolamin baAAdi ma tabayyana lahu alhuda wayattabiAAghayra sabeeli almu/mineena nuwallihi ma tawallawanuslihi jahannama wasaat maseera","juz":5,"page":97},{"s":4,"a":116,"key":"4:116","ar":"إِنَّ ٱللَّهَ لَا يَغْفِرُ أَن يُشْرَكَ بِهِۦ وَيَغْفِرُ مَا دُونَ ذَٰلِكَ لِمَن يَشَآءُ ۚ وَمَن يُشْرِكْ بِٱللَّهِ فَقَدْ ضَلَّ ضَلَـٰلًۢا بَعِيدًا","en":"Indeed, Allāh does not forgive association with Him, but He forgives what is less than that for whom He wills. And he who associates others with Allāh has certainly gone far astray.","tr":"Inna Allaha la yaghfiru anyushraka bihi wayaghfiru ma doona thalika limanyashao waman yushrik billahi faqad dalladalalan baAAeeda","juz":5,"page":97},{"s":4,"a":117,"key":"4:117","ar":"إِن يَدْعُونَ مِن دُونِهِۦٓ إِلَّآ إِنَـٰثًا وَإِن يَدْعُونَ إِلَّا شَيْطَـٰنًا مَّرِيدًا","en":"They call upon instead of Him none but female [deities], and they [actually] call upon none but a rebellious Satan,","tr":"In yadAAoona min doonihi illa inathanwa-in yadAAoona illa shaytanan mareeda","juz":5,"page":97},{"s":4,"a":118,"key":"4:118","ar":"لَّعَنَهُ ٱللَّهُ ۘ وَقَالَ لَأَتَّخِذَنَّ مِنْ عِبَادِكَ نَصِيبًا مَّفْرُوضًا","en":"Whom Allāh has cursed. For he had said, \"I will surely take from among Your servants a specific portion.","tr":"LaAAanahu Allahu waqalalaattakhithanna min AAibadika naseebanmafrooda","juz":5,"page":97},{"s":4,"a":119,"key":"4:119","ar":"وَلَأُضِلَّنَّهُمْ وَلَأُمَنِّيَنَّهُمْ وَلَـَٔامُرَنَّهُمْ فَلَيُبَتِّكُنَّ ءَاذَانَ ٱلْأَنْعَـٰمِ وَلَـَٔامُرَنَّهُمْ فَلَيُغَيِّرُنَّ خَلْقَ ٱللَّهِ ۚ وَمَن يَتَّخِذِ ٱلشَّيْطَـٰنَ وَلِيًّا مِّن دُونِ ٱللَّهِ فَقَدْ خَسِرَ خُسْرَانًا مُّبِينًا","en":"And I will mislead them, and I will arouse in them [sinful] desires, and I will command them so they will slit the ears of cattle, and I will command them so they will change the creation of Allāh.\" And whoever takes Satan as an ally instead of Allāh has certainly sustained a clear loss.","tr":"Walaodillannahum walaomanniyannahumwalaamurannahum falayubattikunna athana al-anAAamiwalaamurannahum falayughayyirunna khalqa Allahiwaman yattakhithi ashshaytana waliyyan mindooni Allahi faqad khasira khusranan mubeena","juz":5,"page":97},{"s":4,"a":120,"key":"4:120","ar":"يَعِدُهُمْ وَيُمَنِّيهِمْ ۖ وَمَا يَعِدُهُمُ ٱلشَّيْطَـٰنُ إِلَّا غُرُورًا","en":"He [i.e., Satan] promises them and arouses desire in them. But Satan does not promise them except delusion.","tr":"YaAAiduhum wayumanneehim wamayaAAiduhumu ashshaytanu illa ghuroora","juz":5,"page":97},{"s":4,"a":121,"key":"4:121","ar":"أُو۟لَـٰٓئِكَ مَأْوَىٰهُمْ جَهَنَّمُ وَلَا يَجِدُونَ عَنْهَا مَحِيصًا","en":"The refuge of those will be Hell, and they will not find from it an escape.","tr":"Ola-ika ma/wahum jahannamuwala yajidoona AAanha maheesa","juz":5,"page":97},{"s":4,"a":122,"key":"4:122","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ سَنُدْخِلُهُمْ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَدًا ۖ وَعْدَ ٱللَّهِ حَقًّا ۚ وَمَنْ أَصْدَقُ مِنَ ٱللَّهِ قِيلًا","en":"But the ones who believe and do righteous deeds - We will admit them to gardens beneath which rivers flow, wherein they will abide forever. [It is] the promise of Allāh, [which is] truth, and who is more truthful than Allāh in statement.","tr":"Wallatheena amanoowaAAamiloo assalihati sanudkhiluhum jannatintajree min tahtiha al-anharu khalideenafeeha abadan waAAda Allahi haqqan waman asdaqumina Allahi qeela","juz":5,"page":98},{"s":4,"a":123,"key":"4:123","ar":"لَّيْسَ بِأَمَانِيِّكُمْ وَلَآ أَمَانِىِّ أَهْلِ ٱلْكِتَـٰبِ ۗ مَن يَعْمَلْ سُوٓءًا يُجْزَ بِهِۦ وَلَا يَجِدْ لَهُۥ مِن دُونِ ٱللَّهِ وَلِيًّا وَلَا نَصِيرًا","en":"It [i.e., Paradise] is not [obtained] by your wishful thinking nor by that of the People of the Scripture. Whoever does a wrong will be recompensed for it, and he will not find besides Allāh a protector or a helper.","tr":"Laysa bi-amaniyyikum wala amaniyyiahli alkitabi man yaAAmal soo-an yujza bihi walayajid lahu min dooni Allahi waliyyan wala naseera","juz":5,"page":98},{"s":4,"a":124,"key":"4:124","ar":"وَمَن يَعْمَلْ مِنَ ٱلصَّـٰلِحَـٰتِ مِن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ فَأُو۟لَـٰٓئِكَ يَدْخُلُونَ ٱلْجَنَّةَ وَلَا يُظْلَمُونَ نَقِيرًا","en":"And whoever does righteous deeds, whether male or female, while being a believer - those will enter Paradise and will not be wronged, [even as much as] the speck on a date seed.","tr":"Waman yaAAmal mina assalihatimin thakarin aw ontha wahuwa mu/minun faola-ikayadkhuloona aljannata wala yuthlamoonanaqeera","juz":5,"page":98},{"s":4,"a":125,"key":"4:125","ar":"وَمَنْ أَحْسَنُ دِينًا مِّمَّنْ أَسْلَمَ وَجْهَهُۥ لِلَّهِ وَهُوَ مُحْسِنٌ وَٱتَّبَعَ مِلَّةَ إِبْرَٰهِيمَ حَنِيفًا ۗ وَٱتَّخَذَ ٱللَّهُ إِبْرَٰهِيمَ خَلِيلًا","en":"And who is better in religion than one who submits himself to Allāh while being a doer of good and follows the religion of Abraham, inclining toward truth? And Allāh took Abraham as an intimate friend.","tr":"Waman ahsanu deenan mimman aslamawajhahu lillahi wahuwa muhsinun wattabaAAamillata ibraheema haneefan wattakhathaAllahu ibraheema khaleela","juz":5,"page":98},{"s":4,"a":126,"key":"4:126","ar":"وَلِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ بِكُلِّ شَىْءٍ مُّحِيطًا","en":"And to Allāh belongs whatever is in the heavens and whatever is on the earth. And ever is Allāh, of all things, encompassing.","tr":"Walillahi ma fee assamawatiwama fee al-ardi wakana Allahubikulli shay-in muheeta","juz":5,"page":98},{"s":4,"a":127,"key":"4:127","ar":"وَيَسْتَفْتُونَكَ فِى ٱلنِّسَآءِ ۖ قُلِ ٱللَّهُ يُفْتِيكُمْ فِيهِنَّ وَمَا يُتْلَىٰ عَلَيْكُمْ فِى ٱلْكِتَـٰبِ فِى يَتَـٰمَى ٱلنِّسَآءِ ٱلَّـٰتِى لَا تُؤْتُونَهُنَّ مَا كُتِبَ لَهُنَّ وَتَرْغَبُونَ أَن تَنكِحُوهُنَّ وَٱلْمُسْتَضْعَفِينَ مِنَ ٱلْوِلْدَٰنِ وَأَن تَقُومُوا۟ لِلْيَتَـٰمَىٰ بِٱلْقِسْطِ ۚ وَمَا تَفْعَلُوا۟ مِنْ خَيْرٍ فَإِنَّ ٱللَّهَ كَانَ بِهِۦ عَلِيمًا","en":"And they request from you, [O Muḥammad], a [legal] ruling concerning women. Say, \"Allāh gives you a ruling about them and [about] what has been recited to you in the Book concerning the orphan girls to whom you do not give what is decreed for them1 - and [yet] you desire to marry them - and concerning the oppressed among children and that you maintain for orphans [their rights] in justice.\" And whatever you do of good - indeed, Allāh is ever Knowing of it.","tr":"Wayastaftoonaka fee annisa-iquli Allahu yufteekum feehinna wama yutlaAAalaykum fee alkitabi fee yatama annisa-iallatee la tu/toonahunna ma kutiba lahunnawatarghaboona an tankihoohunna walmustadAAafeenamina alwildani waan taqoomoo lilyatama bilqistiwama tafAAaloo min khayrin fa-inna Allaha kanabihi AAaleema","juz":5,"page":98},{"s":4,"a":128,"key":"4:128","ar":"وَإِنِ ٱمْرَأَةٌ خَافَتْ مِنۢ بَعْلِهَا نُشُوزًا أَوْ إِعْرَاضًا فَلَا جُنَاحَ عَلَيْهِمَآ أَن يُصْلِحَا بَيْنَهُمَا صُلْحًا ۚ وَٱلصُّلْحُ خَيْرٌ ۗ وَأُحْضِرَتِ ٱلْأَنفُسُ ٱلشُّحَّ ۚ وَإِن تُحْسِنُوا۟ وَتَتَّقُوا۟ فَإِنَّ ٱللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًا","en":"And if a woman fears from her husband contempt or evasion, there is no sin upon them if they make terms of settlement between them - and settlement is best. And present in [human] souls is stinginess.1 But if you do good and fear Allāh - then indeed Allāh is ever, of what you do, Aware.","tr":"Wa-ini imraatun khafat min baAAlihanushoozan aw iAAradan fala junaha AAalayhimaan yusliha baynahuma sulhan wassulhukhayrun waohdirati al-anfusu ashshuhhawa-in tuhsinoo watattaqoo fa-inna Allaha kanabima taAAmaloona khabeera","juz":5,"page":99},{"s":4,"a":129,"key":"4:129","ar":"وَلَن تَسْتَطِيعُوٓا۟ أَن تَعْدِلُوا۟ بَيْنَ ٱلنِّسَآءِ وَلَوْ حَرَصْتُمْ ۖ فَلَا تَمِيلُوا۟ كُلَّ ٱلْمَيْلِ فَتَذَرُوهَا كَٱلْمُعَلَّقَةِ ۚ وَإِن تُصْلِحُوا۟ وَتَتَّقُوا۟ فَإِنَّ ٱللَّهَ كَانَ غَفُورًا رَّحِيمًا","en":"And you will never be able to be equal [in feeling] between wives, even if you should strive [to do so]. So do not incline completely [toward one] and leave another hanging.1 And if you amend [your affairs] and fear Allāh - then indeed, Allāh is ever Forgiving and Merciful.","tr":"Walan tastateeAAoo an taAAdiloobayna annisa-i walaw harastum falatameeloo kulla almayli fatatharooha kalmuAAallaqatiwa-in tuslihoo watattaqoo fa-inna Allaha kanaghafooran raheema","juz":5,"page":99},{"s":4,"a":130,"key":"4:130","ar":"وَإِن يَتَفَرَّقَا يُغْنِ ٱللَّهُ كُلًّا مِّن سَعَتِهِۦ ۚ وَكَانَ ٱللَّهُ وَٰسِعًا حَكِيمًا","en":"But if they separate [by divorce], Allāh will enrich each [of them] from His abundance. And ever is Allāh Encompassing and Wise.","tr":"Wa-in yatafarraqa yughni Allahukullan min saAAatihi wakana Allahu wasiAAan hakeema","juz":5,"page":99},{"s":4,"a":131,"key":"4:131","ar":"وَلِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَلَقَدْ وَصَّيْنَا ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ مِن قَبْلِكُمْ وَإِيَّاكُمْ أَنِ ٱتَّقُوا۟ ٱللَّهَ ۚ وَإِن تَكْفُرُوا۟ فَإِنَّ لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ غَنِيًّا حَمِيدًا","en":"And to Allāh belongs whatever is in the heavens and whatever is on the earth. And We have instructed those who were given the Scripture before you and yourselves to fear Allāh. But if you disbelieve - then to Allāh belongs whatever is in the heavens and whatever is on the earth. And ever is Allāh Free of need and Praiseworthy.","tr":"Walillahi ma fee assamawatiwama fee al-ardi walaqad wassaynaallatheena ootoo alkitaba min qablikum wa-iyyakumani ittaqoo Allaha wa-in takfuroo fa-inna lillahi mafee assamawati wama fee al-ardiwakana Allahu ghaniyyan hameeda","juz":5,"page":99},{"s":4,"a":132,"key":"4:132","ar":"وَلِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًا","en":"And to Allāh belongs whatever is in the heavens and whatever is on the earth. And sufficient is Allāh as Disposer of affairs.1","tr":"Walillahi ma fee assamawatiwama fee al-ardi wakafa billahiwakeela","juz":5,"page":99},{"s":4,"a":133,"key":"4:133","ar":"إِن يَشَأْ يُذْهِبْكُمْ أَيُّهَا ٱلنَّاسُ وَيَأْتِ بِـَٔاخَرِينَ ۚ وَكَانَ ٱللَّهُ عَلَىٰ ذَٰلِكَ قَدِيرًا","en":"If He wills, He can do away with you, O people, and bring others [in your place]. And ever is Allāh competent to do that.","tr":"In yasha/ yuthhibkum ayyuha annasuwaya/ti bi-akhareena wakana Allahu AAalathalika qadeera","juz":5,"page":99},{"s":4,"a":134,"key":"4:134","ar":"مَّن كَانَ يُرِيدُ ثَوَابَ ٱلدُّنْيَا فَعِندَ ٱللَّهِ ثَوَابُ ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ ۚ وَكَانَ ٱللَّهُ سَمِيعًۢا بَصِيرًا","en":"Whoever desires the reward of this world - then with Allāh is the reward of this world and the Hereafter. And ever is Allāh Hearing and Seeing.","tr":"Man kana yureedu thawaba addunyafaAAinda Allahi thawabu addunya wal-akhiratiwakana Allahu sameeAAan baseera","juz":5,"page":99},{"s":4,"a":135,"key":"4:135","ar":"۞ يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُونُوا۟ قَوَّٰمِينَ بِٱلْقِسْطِ شُهَدَآءَ لِلَّهِ وَلَوْ عَلَىٰٓ أَنفُسِكُمْ أَوِ ٱلْوَٰلِدَيْنِ وَٱلْأَقْرَبِينَ ۚ إِن يَكُنْ غَنِيًّا أَوْ فَقِيرًا فَٱللَّهُ أَوْلَىٰ بِهِمَا ۖ فَلَا تَتَّبِعُوا۟ ٱلْهَوَىٰٓ أَن تَعْدِلُوا۟ ۚ وَإِن تَلْوُۥٓا۟ أَوْ تُعْرِضُوا۟ فَإِنَّ ٱللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًا","en":"O you who have believed, be persistently standing firm in justice, witnesses for Allāh, even if it be against yourselves or parents and relatives. Whether one is rich or poor, Allāh is more worthy of both.1 So follow not [personal] inclination, lest you not be just. And if you distort [your testimony] or refuse [to give it], then indeed Allāh is ever, of what you do, Aware.","tr":"Ya ayyuha allatheena amanookoonoo qawwameena bilqisti shuhadaalillahi walaw AAala anfusikum awi alwalidayniwal-aqrabeena in yakun ghaniyyan aw faqeeran fallahuawla bihima fala tattabiAAoo alhawaan taAAdiloo wa-in talwoo aw tuAAridoo fa-inna Allahakana bima taAAmaloona khabeera","juz":5,"page":100},{"s":4,"a":136,"key":"4:136","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ ءَامِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَٱلْكِتَـٰبِ ٱلَّذِى نَزَّلَ عَلَىٰ رَسُولِهِۦ وَٱلْكِتَـٰبِ ٱلَّذِىٓ أَنزَلَ مِن قَبْلُ ۚ وَمَن يَكْفُرْ بِٱللَّهِ وَمَلَـٰٓئِكَتِهِۦ وَكُتُبِهِۦ وَرُسُلِهِۦ وَٱلْيَوْمِ ٱلْـَٔاخِرِ فَقَدْ ضَلَّ ضَلَـٰلًۢا بَعِيدًا","en":"O you who have believed, believe1 in Allāh and His Messenger and the Book that He sent down upon His Messenger and the Scripture which He sent down before. And whoever disbelieves in Allāh, His angels, His books, His messengers, and the Last Day has certainly gone far astray.","tr":"Ya ayyuha allatheena amanooaminoo billahi warasoolihi walkitabiallathee nazzala AAala rasoolihi walkitabiallathee anzala min qablu waman yakfur billahiwamala-ikatihi wakutubihi warusulihi walyawmi al-akhirifaqad dalla dalalan baAAeeda","juz":5,"page":100},{"s":4,"a":137,"key":"4:137","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ ثُمَّ كَفَرُوا۟ ثُمَّ ءَامَنُوا۟ ثُمَّ كَفَرُوا۟ ثُمَّ ٱزْدَادُوا۟ كُفْرًا لَّمْ يَكُنِ ٱللَّهُ لِيَغْفِرَ لَهُمْ وَلَا لِيَهْدِيَهُمْ سَبِيلًۢا","en":"Indeed, those who have believed then disbelieved, then believed then disbelieved, and then increased in disbelief - never will Allāh forgive them, nor will He guide them to a way.","tr":"Inna allatheena amanoo thummakafaroo thumma amanoo thumma kafaroo thumma izdadookufran lam yakuni Allahu liyaghfira lahum walaliyahdiyahum sabeela","juz":5,"page":100},{"s":4,"a":138,"key":"4:138","ar":"بَشِّرِ ٱلْمُنَـٰفِقِينَ بِأَنَّ لَهُمْ عَذَابًا أَلِيمًا","en":"Give tidings to the hypocrites that there is for them a painful punishment -","tr":"Bashshiri almunafiqeena bi-annalahum AAathaban aleema","juz":5,"page":100},{"s":4,"a":139,"key":"4:139","ar":"ٱلَّذِينَ يَتَّخِذُونَ ٱلْكَـٰفِرِينَ أَوْلِيَآءَ مِن دُونِ ٱلْمُؤْمِنِينَ ۚ أَيَبْتَغُونَ عِندَهُمُ ٱلْعِزَّةَ فَإِنَّ ٱلْعِزَّةَ لِلَّهِ جَمِيعًا","en":"Those who take disbelievers as allies instead of the believers. Do they seek with them honor [through power]? But indeed, honor belongs to Allāh entirely.1","tr":"Allatheena yattakhithoona alkafireenaawliyaa min dooni almu/mineena ayabtaghoona AAindahumualAAizzata fa-inna alAAizzata lillahi jameeAAa","juz":5,"page":100},{"s":4,"a":140,"key":"4:140","ar":"وَقَدْ نَزَّلَ عَلَيْكُمْ فِى ٱلْكِتَـٰبِ أَنْ إِذَا سَمِعْتُمْ ءَايَـٰتِ ٱللَّهِ يُكْفَرُ بِهَا وَيُسْتَهْزَأُ بِهَا فَلَا تَقْعُدُوا۟ مَعَهُمْ حَتَّىٰ يَخُوضُوا۟ فِى حَدِيثٍ غَيْرِهِۦٓ ۚ إِنَّكُمْ إِذًا مِّثْلُهُمْ ۗ إِنَّ ٱللَّهَ جَامِعُ ٱلْمُنَـٰفِقِينَ وَٱلْكَـٰفِرِينَ فِى جَهَنَّمَ جَمِيعًا","en":"And it has already come down to you in the Book [i.e., the Qur’ān] that when you hear the verses of Allāh [recited], they are denied [by them] and ridiculed; so do not sit with them until they enter into another conversation. Indeed, you would then be like them.1 Indeed, Allāh will gather the hypocrites and disbelievers in Hell all together -","tr":"Waqad nazzala AAalaykum fee alkitabian itha samiAAtum ayati Allahiyukfaru biha wayustahzao biha fala taqAAudoomaAAahum hatta yakhoodoo fee hadeethinghayrihi innakum ithan mithluhum inna Allaha jamiAAualmunafiqeena walkafireena fee jahannamajameeAAa","juz":5,"page":100},{"s":4,"a":141,"key":"4:141","ar":"ٱلَّذِينَ يَتَرَبَّصُونَ بِكُمْ فَإِن كَانَ لَكُمْ فَتْحٌ مِّنَ ٱللَّهِ قَالُوٓا۟ أَلَمْ نَكُن مَّعَكُمْ وَإِن كَانَ لِلْكَـٰفِرِينَ نَصِيبٌ قَالُوٓا۟ أَلَمْ نَسْتَحْوِذْ عَلَيْكُمْ وَنَمْنَعْكُم مِّنَ ٱلْمُؤْمِنِينَ ۚ فَٱللَّهُ يَحْكُمُ بَيْنَكُمْ يَوْمَ ٱلْقِيَـٰمَةِ ۗ وَلَن يَجْعَلَ ٱللَّهُ لِلْكَـٰفِرِينَ عَلَى ٱلْمُؤْمِنِينَ سَبِيلًا","en":"Those who wait [and watch] you. Then if you gain a victory from Allāh, they say, \"Were we not with you?\" But if the disbelievers have a success, they say [to them], \"Did we not gain the advantage over you, but we protected you from the believers?\" Allāh will judge between [all of] you on the Day of Resurrection, and never will Allāh give the disbelievers over the believers a way [to overcome them].1","tr":"Allatheena yatarabbasoonabikum fa-in kana lakum fathun mina Allahi qalooalam nakun maAAakum wa-in kana lilkafireena naseebunqaloo alam nastahwith AAalaykum wanamnaAAkummina almu/mineena fallahu yahkumu baynakumyawma alqiyamati walan yajAAala Allahu lilkafireenaAAala almu/mineena sabeela","juz":5,"page":101},{"s":4,"a":142,"key":"4:142","ar":"إِنَّ ٱلْمُنَـٰفِقِينَ يُخَـٰدِعُونَ ٱللَّهَ وَهُوَ خَـٰدِعُهُمْ وَإِذَا قَامُوٓا۟ إِلَى ٱلصَّلَوٰةِ قَامُوا۟ كُسَالَىٰ يُرَآءُونَ ٱلنَّاسَ وَلَا يَذْكُرُونَ ٱللَّهَ إِلَّا قَلِيلًا","en":"Indeed, the hypocrites [think to] deceive Allāh, but He is deceiving them. And when they stand for prayer, they stand lazily, showing [themselves to] the people and not remembering Allāh except a little,","tr":"Inna almunafiqeena yukhadiAAoonaAllaha wahuwa khadiAAuhum wa-itha qamooila assalati qamoo kusalayuraoona annasa wala yathkuroonaAllaha illa qaleela","juz":5,"page":101},{"s":4,"a":143,"key":"4:143","ar":"مُّذَبْذَبِينَ بَيْنَ ذَٰلِكَ لَآ إِلَىٰ هَـٰٓؤُلَآءِ وَلَآ إِلَىٰ هَـٰٓؤُلَآءِ ۚ وَمَن يُضْلِلِ ٱللَّهُ فَلَن تَجِدَ لَهُۥ سَبِيلًا","en":"Wavering between them, [belonging] neither to these [i.e., the believers] nor to those [i.e., the disbelievers]. And whoever Allāh sends astray - never will you find for him a way.","tr":"Muthabthabeena bayna thalikala ila haola-i wala ilahaola-i waman yudlili Allahu falantajida lahu sabeela","juz":5,"page":101},{"s":4,"a":144,"key":"4:144","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ ٱلْكَـٰفِرِينَ أَوْلِيَآءَ مِن دُونِ ٱلْمُؤْمِنِينَ ۚ أَتُرِيدُونَ أَن تَجْعَلُوا۟ لِلَّهِ عَلَيْكُمْ سُلْطَـٰنًا مُّبِينًا","en":"O you who have believed, do not take the disbelievers as allies instead of the believers. Do you wish to give Allāh against yourselves a clear case?","tr":"Ya ayyuha allatheena amanoola tattakhithoo alkafireena awliyaamin dooni almu/mineena atureedoona an tajAAaloo lillahiAAalaykum sultanan mubeena","juz":5,"page":101},{"s":4,"a":145,"key":"4:145","ar":"إِنَّ ٱلْمُنَـٰفِقِينَ فِى ٱلدَّرْكِ ٱلْأَسْفَلِ مِنَ ٱلنَّارِ وَلَن تَجِدَ لَهُمْ نَصِيرًا","en":"Indeed, the hypocrites will be in the lowest depths of the Fire - and never will you find for them a helper -","tr":"Inna almunafiqeena fee addarkial-asfali mina annari walan tajida lahum naseera","juz":5,"page":101},{"s":4,"a":146,"key":"4:146","ar":"إِلَّا ٱلَّذِينَ تَابُوا۟ وَأَصْلَحُوا۟ وَٱعْتَصَمُوا۟ بِٱللَّهِ وَأَخْلَصُوا۟ دِينَهُمْ لِلَّهِ فَأُو۟لَـٰٓئِكَ مَعَ ٱلْمُؤْمِنِينَ ۖ وَسَوْفَ يُؤْتِ ٱللَّهُ ٱلْمُؤْمِنِينَ أَجْرًا عَظِيمًا","en":"Except for those who repent, correct themselves, hold fast to Allāh, and are sincere in their religion for Allāh, for those will be with the believers. And Allāh is going to give the believers a great reward.","tr":"Illa allatheena taboowaaslahoo waAAtasamoo billahiwaakhlasoo deenahum lillahi faola-ika maAAaalmu/mineena wasawfa yu/ti Allahu almu/mineena ajran AAatheema","juz":5,"page":101},{"s":4,"a":147,"key":"4:147","ar":"مَّا يَفْعَلُ ٱللَّهُ بِعَذَابِكُمْ إِن شَكَرْتُمْ وَءَامَنتُمْ ۚ وَكَانَ ٱللَّهُ شَاكِرًا عَلِيمًا","en":"What would Allāh do with [i.e., gain from] your punishment if you are grateful and believe? And ever is Allāh Appreciative1 and Knowing.","tr":"Ma yafAAalu Allahu biAAathabikumin shakartum waamantum wakana Allahu shakiranAAaleema","juz":5,"page":101},{"s":4,"a":148,"key":"4:148","ar":"۞ لَّا يُحِبُّ ٱللَّهُ ٱلْجَهْرَ بِٱلسُّوٓءِ مِنَ ٱلْقَوْلِ إِلَّا مَن ظُلِمَ ۚ وَكَانَ ٱللَّهُ سَمِيعًا عَلِيمًا","en":"Allāh does not like the public mention of evil except by one who has been wronged. And ever is Allāh Hearing and Knowing.","tr":"La yuhibbu Allahualjahra bissoo-i mina alqawli illa man thulimawakana Allahu sameeAAan AAaleema","juz":6,"page":102},{"s":4,"a":149,"key":"4:149","ar":"إِن تُبْدُوا۟ خَيْرًا أَوْ تُخْفُوهُ أَوْ تَعْفُوا۟ عَن سُوٓءٍ فَإِنَّ ٱللَّهَ كَانَ عَفُوًّا قَدِيرًا","en":"If [instead] you show [some] good or conceal it or pardon an offense - indeed, Allāh is ever Pardoning and Competent.1","tr":"In tubdoo khayran aw tukhfoohu aw taAAfooAAan soo-in fa-inna Allaha kana AAafuwwan qadeera","juz":6,"page":102},{"s":4,"a":150,"key":"4:150","ar":"إِنَّ ٱلَّذِينَ يَكْفُرُونَ بِٱللَّهِ وَرُسُلِهِۦ وَيُرِيدُونَ أَن يُفَرِّقُوا۟ بَيْنَ ٱللَّهِ وَرُسُلِهِۦ وَيَقُولُونَ نُؤْمِنُ بِبَعْضٍ وَنَكْفُرُ بِبَعْضٍ وَيُرِيدُونَ أَن يَتَّخِذُوا۟ بَيْنَ ذَٰلِكَ سَبِيلًا","en":"Indeed, those who disbelieve in Allāh and His messengers and wish to discriminate between Allāh and His messengers and say, \"We believe in some and disbelieve in others,\" and wish to adopt a way in between -","tr":"Inna allatheena yakfuroona billahiwarusulihi wayureedoona an yufarriqoo bayna Allahiwarusulihi wayaqooloona nu/minu bibaAAdin wanakfuru bibaAAdinwayureedoona an yattakhithoo bayna thalika sabeela","juz":6,"page":102},{"s":4,"a":151,"key":"4:151","ar":"أُو۟لَـٰٓئِكَ هُمُ ٱلْكَـٰفِرُونَ حَقًّا ۚ وَأَعْتَدْنَا لِلْكَـٰفِرِينَ عَذَابًا مُّهِينًا","en":"Those are the disbelievers, truly. And We have prepared for the disbelievers a humiliating punishment.","tr":"Ola-ika humu alkafiroona haqqanwaaAAtadna lilkafireena AAathaban muheena","juz":6,"page":102},{"s":4,"a":152,"key":"4:152","ar":"وَٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرُسُلِهِۦ وَلَمْ يُفَرِّقُوا۟ بَيْنَ أَحَدٍ مِّنْهُمْ أُو۟لَـٰٓئِكَ سَوْفَ يُؤْتِيهِمْ أُجُورَهُمْ ۗ وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًا","en":"But they who believe in Allāh and His messengers and do not discriminate between any of them - to those He is going to give their rewards. And ever is Allāh Forgiving and Merciful.","tr":"Wallatheena amanoo billahiwarusulihi walam yufarriqoo bayna ahadin minhum ola-ikasawfa yu/teehim ojoorahum wakana Allahu ghafooranraheema","juz":6,"page":102},{"s":4,"a":153,"key":"4:153","ar":"يَسْـَٔلُكَ أَهْلُ ٱلْكِتَـٰبِ أَن تُنَزِّلَ عَلَيْهِمْ كِتَـٰبًا مِّنَ ٱلسَّمَآءِ ۚ فَقَدْ سَأَلُوا۟ مُوسَىٰٓ أَكْبَرَ مِن ذَٰلِكَ فَقَالُوٓا۟ أَرِنَا ٱللَّهَ جَهْرَةً فَأَخَذَتْهُمُ ٱلصَّـٰعِقَةُ بِظُلْمِهِمْ ۚ ثُمَّ ٱتَّخَذُوا۟ ٱلْعِجْلَ مِنۢ بَعْدِ مَا جَآءَتْهُمُ ٱلْبَيِّنَـٰتُ فَعَفَوْنَا عَن ذَٰلِكَ ۚ وَءَاتَيْنَا مُوسَىٰ سُلْطَـٰنًا مُّبِينًا","en":"The People of the Scripture ask you to bring down to them a book from the heaven. But they had asked of Moses [even] greater than that and said, \"Show us Allāh outright,\" so the thunderbolt struck them for their wrongdoing. Then they took the calf [for worship] after clear evidences had come to them, and We pardoned that. And We gave Moses a clear authority.","tr":"Yas-aluka ahlu alkitabi an tunazzilaAAalayhim kitaban mina assama-i faqadsaaloo moosa akbara min thalika faqaloo arinaAllaha jahratan faakhathat-humu assaAAiqatubithulmihim thumma ittakhathoo alAAijla minbaAAdi ma jaat-humu albayyinatu faAAafawnaAAan thalika waatayna moosa sultananmubeena","juz":6,"page":102},{"s":4,"a":154,"key":"4:154","ar":"وَرَفَعْنَا فَوْقَهُمُ ٱلطُّورَ بِمِيثَـٰقِهِمْ وَقُلْنَا لَهُمُ ٱدْخُلُوا۟ ٱلْبَابَ سُجَّدًا وَقُلْنَا لَهُمْ لَا تَعْدُوا۟ فِى ٱلسَّبْتِ وَأَخَذْنَا مِنْهُم مِّيثَـٰقًا غَلِيظًا","en":"And We raised over them the mount for [refusal of] their covenant; and We said to them, \"Enter the gate bowing humbly\"; and We said to them, \"Do not transgress on the sabbath\"; and We took from them a solemn covenant.","tr":"WarafaAAna fawqahumu attoorabimeethaqihim waqulna lahumu odkhuloo albabasujjadan waqulna lahum la taAAdoo fee assabtiwaakhathna minhum meethaqan ghaleetha","juz":6,"page":102},{"s":4,"a":155,"key":"4:155","ar":"فَبِمَا نَقْضِهِم مِّيثَـٰقَهُمْ وَكُفْرِهِم بِـَٔايَـٰتِ ٱللَّهِ وَقَتْلِهِمُ ٱلْأَنۢبِيَآءَ بِغَيْرِ حَقٍّ وَقَوْلِهِمْ قُلُوبُنَا غُلْفٌۢ ۚ بَلْ طَبَعَ ٱللَّهُ عَلَيْهَا بِكُفْرِهِمْ فَلَا يُؤْمِنُونَ إِلَّا قَلِيلًا","en":"And [We cursed them]1 for their breaking of the covenant and their disbelief in the signs of Allāh and their killing of the prophets without right and their saying, \"Our hearts are wrapped\" [i.e., sealed against reception]. Rather, Allāh has sealed them because of their disbelief, so they believe not, except for a few.2","tr":"Fabima naqdihim meethaqahumwakufrihim bi-ayati Allahi waqatlihimual-anbiyaa bighayri haqqin waqawlihim quloobunaghulfun bal tabaAAa Allahu AAalayhabikufrihim fala yu/minoona illa qaleela","juz":6,"page":103},{"s":4,"a":156,"key":"4:156","ar":"وَبِكُفْرِهِمْ وَقَوْلِهِمْ عَلَىٰ مَرْيَمَ بُهْتَـٰنًا عَظِيمًا","en":"And [We cursed them] for their disbelief and their saying against Mary a great slander1","tr":"Wabikufrihim waqawlihim AAalamaryama buhtanan AAatheema","juz":6,"page":103},{"s":4,"a":157,"key":"4:157","ar":"وَقَوْلِهِمْ إِنَّا قَتَلْنَا ٱلْمَسِيحَ عِيسَى ٱبْنَ مَرْيَمَ رَسُولَ ٱللَّهِ وَمَا قَتَلُوهُ وَمَا صَلَبُوهُ وَلَـٰكِن شُبِّهَ لَهُمْ ۚ وَإِنَّ ٱلَّذِينَ ٱخْتَلَفُوا۟ فِيهِ لَفِى شَكٍّ مِّنْهُ ۚ مَا لَهُم بِهِۦ مِنْ عِلْمٍ إِلَّا ٱتِّبَاعَ ٱلظَّنِّ ۚ وَمَا قَتَلُوهُ يَقِينًۢا","en":"And [for] their saying, \"Indeed, we have killed the Messiah, Jesus the son of Mary, the messenger of Allāh.\" And they did not kill him, nor did they crucify him; but [another] was made to resemble him to them. And indeed, those who differ over it are in doubt about it. They have no knowledge of it except the following of assumption. And they did not kill him, for certain.1","tr":"Waqawlihim inna qatalnaalmaseeha AAeesa ibna maryama rasoola Allahiwama qataloohu wama salaboohu walakinshubbiha lahum wa-inna allatheena ikhtalafoo feehi lafeeshakkin minhu ma lahum bihi min AAilmin illa ittibaAAaaththanni wama qataloohu yaqeena","juz":6,"page":103},{"s":4,"a":158,"key":"4:158","ar":"بَل رَّفَعَهُ ٱللَّهُ إِلَيْهِ ۚ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمًا","en":"Rather, Allāh raised him to Himself. And ever is Allāh Exalted in Might and Wise.","tr":"Bal rafaAAahu Allahu ilayhi wakanaAllahu AAazeezan hakeema","juz":6,"page":103},{"s":4,"a":159,"key":"4:159","ar":"وَإِن مِّنْ أَهْلِ ٱلْكِتَـٰبِ إِلَّا لَيُؤْمِنَنَّ بِهِۦ قَبْلَ مَوْتِهِۦ ۖ وَيَوْمَ ٱلْقِيَـٰمَةِ يَكُونُ عَلَيْهِمْ شَهِيدًا","en":"And there is none from the People of the Scripture but that he will surely believe in him [i.e., Jesus] before his death.1 And on the Day of Resurrection he will be against them a witness.","tr":"Wa-in min ahli alkitabi illalayu/minanna bihi qabla mawtihi wayawma alqiyamati yakoonuAAalayhim shaheeda","juz":6,"page":103},{"s":4,"a":160,"key":"4:160","ar":"فَبِظُلْمٍ مِّنَ ٱلَّذِينَ هَادُوا۟ حَرَّمْنَا عَلَيْهِمْ طَيِّبَـٰتٍ أُحِلَّتْ لَهُمْ وَبِصَدِّهِمْ عَن سَبِيلِ ٱللَّهِ كَثِيرًا","en":"For wrongdoing on the part of the Jews, We made unlawful for them [certain] good foods which had been lawful to them, and for their averting from the way of Allāh many [people],","tr":"Fabithulmin mina allatheenahadoo harramna AAalayhim tayyibatinohillat lahum wabisaddihim AAan sabeeli Allahikatheera","juz":6,"page":103},{"s":4,"a":161,"key":"4:161","ar":"وَأَخْذِهِمُ ٱلرِّبَوٰا۟ وَقَدْ نُهُوا۟ عَنْهُ وَأَكْلِهِمْ أَمْوَٰلَ ٱلنَّاسِ بِٱلْبَـٰطِلِ ۚ وَأَعْتَدْنَا لِلْكَـٰفِرِينَ مِنْهُمْ عَذَابًا أَلِيمًا","en":"And [for] their taking of usury while they had been forbidden from it, and their consuming of the people's wealth unjustly. And We have prepared for the disbelievers among them a painful punishment.","tr":"Waakhthihimu arribawaqad nuhoo AAanhu waaklihim amwala annasibilbatili waaAAtadna lilkafireenaminhum AAathaban aleema","juz":6,"page":103},{"s":4,"a":162,"key":"4:162","ar":"لَّـٰكِنِ ٱلرَّٰسِخُونَ فِى ٱلْعِلْمِ مِنْهُمْ وَٱلْمُؤْمِنُونَ يُؤْمِنُونَ بِمَآ أُنزِلَ إِلَيْكَ وَمَآ أُنزِلَ مِن قَبْلِكَ ۚ وَٱلْمُقِيمِينَ ٱلصَّلَوٰةَ ۚ وَٱلْمُؤْتُونَ ٱلزَّكَوٰةَ وَٱلْمُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ أُو۟لَـٰٓئِكَ سَنُؤْتِيهِمْ أَجْرًا عَظِيمًا","en":"But those firm in knowledge among them and the believers believe in what has been revealed to you, [O Muḥammad], and what was revealed before you. And the establishers of prayer [especially] and the givers of zakāh and the believers in Allāh and the Last Day - those We will give a great reward.","tr":"Lakini arrasikhoonafee alAAilmi minhum walmu/minoona yu/minoona bimaonzila ilayka wama onzila min qablika walmuqeemeenaassalata walmu/toona azzakatawalmu/minoona billahi walyawmi al-akhiriola-ika sanu/teehim ajran AAatheema","juz":6,"page":103},{"s":4,"a":163,"key":"4:163","ar":"۞ إِنَّآ أَوْحَيْنَآ إِلَيْكَ كَمَآ أَوْحَيْنَآ إِلَىٰ نُوحٍ وَٱلنَّبِيِّـۧنَ مِنۢ بَعْدِهِۦ ۚ وَأَوْحَيْنَآ إِلَىٰٓ إِبْرَٰهِيمَ وَإِسْمَـٰعِيلَ وَإِسْحَـٰقَ وَيَعْقُوبَ وَٱلْأَسْبَاطِ وَعِيسَىٰ وَأَيُّوبَ وَيُونُسَ وَهَـٰرُونَ وَسُلَيْمَـٰنَ ۚ وَءَاتَيْنَا دَاوُۥدَ زَبُورًا","en":"Indeed, We have revealed to you, [O Muḥammad], as We revealed to Noah and the prophets after him. And We revealed to Abraham, Ishmael, Isaac, Jacob, the Descendants,1 Jesus, Job, Jonah, Aaron, and Solomon, and to David We gave the book [of Psalms].","tr":"Inna awhayna ilaykakama awhayna ila noohin wannabiyyeenamin baAAdihi waawhayna ila ibraheemawa-ismaAAeela wa-ishaqa wayaAAqooba wal-asbatiwaAAeesa waayyooba wayoonusa waharoona wasulaymanawaatayna dawooda zaboora","juz":6,"page":104},{"s":4,"a":164,"key":"4:164","ar":"وَرُسُلًا قَدْ قَصَصْنَـٰهُمْ عَلَيْكَ مِن قَبْلُ وَرُسُلًا لَّمْ نَقْصُصْهُمْ عَلَيْكَ ۚ وَكَلَّمَ ٱللَّهُ مُوسَىٰ تَكْلِيمًا","en":"And [We sent] messengers about whom We have related [their stories] to you before and messengers about whom We have not related to you. And Allāh spoke to Moses with [direct] speech.","tr":"Warusulan qad qasasnahumAAalayka min qablu warusulan lam naqsushum AAalaykawakallama Allahu moosa takleema","juz":6,"page":104},{"s":4,"a":165,"key":"4:165","ar":"رُّسُلًا مُّبَشِّرِينَ وَمُنذِرِينَ لِئَلَّا يَكُونَ لِلنَّاسِ عَلَى ٱللَّهِ حُجَّةٌۢ بَعْدَ ٱلرُّسُلِ ۚ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمًا","en":"[We sent] messengers as bringers of good tidings and warners so that mankind will have no argument against Allāh after the messengers. And ever is Allāh Exalted in Might and Wise.","tr":"Rusulan mubashshireena wamunthireenali-alla yakoona linnasi AAala Allahihujjatun baAAda arrusuli wakana AllahuAAazeezan hakeema","juz":6,"page":104},{"s":4,"a":166,"key":"4:166","ar":"لَّـٰكِنِ ٱللَّهُ يَشْهَدُ بِمَآ أَنزَلَ إِلَيْكَ ۖ أَنزَلَهُۥ بِعِلْمِهِۦ ۖ وَٱلْمَلَـٰٓئِكَةُ يَشْهَدُونَ ۚ وَكَفَىٰ بِٱللَّهِ شَهِيدًا","en":"But Allāh bears witness to that which He has revealed to you. He has sent it down with His knowledge, and the angels bear witness [as well]. And sufficient is Allāh as Witness.","tr":"Lakini Allahu yashhadu bimaanzala ilayka anzalahu biAAilmihi walmala-ikatuyashhadoona wakafa billahi shaheeda","juz":6,"page":104},{"s":4,"a":167,"key":"4:167","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ قَدْ ضَلُّوا۟ ضَلَـٰلًۢا بَعِيدًا","en":"Indeed, those who disbelieve and avert [people] from the way of Allāh have certainly gone far astray.","tr":"Inna allatheena kafaroo wasaddooAAan sabeeli Allahi qad dalloo dalalanbaAAeeda","juz":6,"page":104},{"s":4,"a":168,"key":"4:168","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَظَلَمُوا۟ لَمْ يَكُنِ ٱللَّهُ لِيَغْفِرَ لَهُمْ وَلَا لِيَهْدِيَهُمْ طَرِيقًا","en":"Indeed, those who disbelieve and commit wrong [or injustice] - never will Allāh forgive them, nor will He guide them to a path,","tr":"Inna allatheena kafaroo wathalamoolam yakuni Allahu liyaghfira lahum walaliyahdiyahum tareeqa","juz":6,"page":104},{"s":4,"a":169,"key":"4:169","ar":"إِلَّا طَرِيقَ جَهَنَّمَ خَـٰلِدِينَ فِيهَآ أَبَدًا ۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرًا","en":"Except the path of Hell; they will abide therein forever. And that, for Allāh, is [always] easy.","tr":"Illa tareeqa jahannama khalideenafeeha abadan wakana thalika AAala Allahiyaseera","juz":6,"page":104},{"s":4,"a":170,"key":"4:170","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ قَدْ جَآءَكُمُ ٱلرَّسُولُ بِٱلْحَقِّ مِن رَّبِّكُمْ فَـَٔامِنُوا۟ خَيْرًا لَّكُمْ ۚ وَإِن تَكْفُرُوا۟ فَإِنَّ لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًا","en":"O mankind, the Messenger has come to you with the truth from your Lord, so believe; it is better for you. But if you disbelieve - then indeed, to Allāh belongs whatever is in the heavens and earth. And ever is Allāh Knowing and Wise.","tr":"Ya ayyuha annasuqad jaakumu arrasoolu bilhaqqi minrabbikum faaminoo khayran lakum wa-in takfuroo fa-innalillahi ma fee assamawati wal-ardiwakana Allahu AAaleeman hakeema","juz":6,"page":104},{"s":4,"a":171,"key":"4:171","ar":"يَـٰٓأَهْلَ ٱلْكِتَـٰبِ لَا تَغْلُوا۟ فِى دِينِكُمْ وَلَا تَقُولُوا۟ عَلَى ٱللَّهِ إِلَّا ٱلْحَقَّ ۚ إِنَّمَا ٱلْمَسِيحُ عِيسَى ٱبْنُ مَرْيَمَ رَسُولُ ٱللَّهِ وَكَلِمَتُهُۥٓ أَلْقَىٰهَآ إِلَىٰ مَرْيَمَ وَرُوحٌ مِّنْهُ ۖ فَـَٔامِنُوا۟ بِٱللَّهِ وَرُسُلِهِۦ ۖ وَلَا تَقُولُوا۟ ثَلَـٰثَةٌ ۚ ٱنتَهُوا۟ خَيْرًا لَّكُمْ ۚ إِنَّمَا ٱللَّهُ إِلَـٰهٌ وَٰحِدٌ ۖ سُبْحَـٰنَهُۥٓ أَن يَكُونَ لَهُۥ وَلَدٌ ۘ لَّهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَكَفَىٰ بِٱللَّهِ وَكِيلًا","en":"O People of the Scripture, do not commit excess in your religion1 or say about Allāh except the truth. The Messiah, Jesus the son of Mary, was but a messenger of Allāh and His word which He directed to Mary and a soul [created at a command] from Him. So believe in Allāh and His messengers. And do not say, \"Three\"; desist - it is better for you. Indeed, Allāh is but one God. Exalted is He above having a son. To Him belongs whatever is in the heavens and whatever is on the earth. And sufficient is Allāh as Disposer of affairs.","tr":"Ya ahla alkitabi lataghloo fee deenikum wala taqooloo AAala Allahiilla alhaqqa innama almaseehu AAeesaibnu maryama rasoolu Allahi wakalimatuhu alqahaila maryama waroohun minhu faaminoo billahiwarusulihi wala taqooloo thalathatun intahookhayran lakum innama Allahu ilahun wahidunsubhanahu an yakoona lahu waladun lahu ma fee assamawatiwama fee al-ardi wakafa billahiwakeela","juz":6,"page":105},{"s":4,"a":172,"key":"4:172","ar":"لَّن يَسْتَنكِفَ ٱلْمَسِيحُ أَن يَكُونَ عَبْدًا لِّلَّهِ وَلَا ٱلْمَلَـٰٓئِكَةُ ٱلْمُقَرَّبُونَ ۚ وَمَن يَسْتَنكِفْ عَنْ عِبَادَتِهِۦ وَيَسْتَكْبِرْ فَسَيَحْشُرُهُمْ إِلَيْهِ جَمِيعًا","en":"Never would the Messiah disdain to be a servant of Allāh, nor would the angels near [to Him]. And whoever disdains His worship and is arrogant - He will gather them to Himself all together.","tr":"Lan yastankifa almaseehu an yakoonaAAabdan lillahi wala almala-ikatualmuqarraboona waman yastankif AAan AAibadatihiwayastakbir fasayahshuruhum ilayhi jameeAAa","juz":6,"page":105},{"s":4,"a":173,"key":"4:173","ar":"فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ فَيُوَفِّيهِمْ أُجُورَهُمْ وَيَزِيدُهُم مِّن فَضْلِهِۦ ۖ وَأَمَّا ٱلَّذِينَ ٱسْتَنكَفُوا۟ وَٱسْتَكْبَرُوا۟ فَيُعَذِّبُهُمْ عَذَابًا أَلِيمًا وَلَا يَجِدُونَ لَهُم مِّن دُونِ ٱللَّهِ وَلِيًّا وَلَا نَصِيرًا","en":"And as for those who believed and did righteous deeds, He will give them in full their rewards and grant them extra from His bounty. But as for those who disdained and were arrogant, He will punish them with a painful punishment, and they will not find for themselves besides Allāh any protector or helper.","tr":"Faamma allatheena amanoowaAAamiloo assalihati fayuwaffeehimojoorahum wayazeeduhum min fadlihi waamma allatheenaistankafoo wastakbaroo fayuAAaththibuhum AAathabanaleeman wala yajidoona lahum min dooni Allahiwaliyyan wala naseera","juz":6,"page":105},{"s":4,"a":174,"key":"4:174","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ قَدْ جَآءَكُم بُرْهَـٰنٌ مِّن رَّبِّكُمْ وَأَنزَلْنَآ إِلَيْكُمْ نُورًا مُّبِينًا","en":"O mankind, there has come to you a conclusive proof from your Lord, and We have sent down to you a clear light.1","tr":"Ya ayyuha annasuqad jaakum burhanun min rabbikum waanzalnailaykum nooran mubeena","juz":6,"page":105},{"s":4,"a":175,"key":"4:175","ar":"فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَٱعْتَصَمُوا۟ بِهِۦ فَسَيُدْخِلُهُمْ فِى رَحْمَةٍ مِّنْهُ وَفَضْلٍ وَيَهْدِيهِمْ إِلَيْهِ صِرَٰطًا مُّسْتَقِيمًا","en":"So those who believe in Allāh and hold fast to Him - He will admit them to mercy from Himself and bounty and guide them to Himself on a straight path.","tr":"Faamma allatheena amanoobillahi waAAtasamoo bihifasayudkhiluhum fee rahmatin minhu wafadlinwayahdeehim ilayhi siratan mustaqeema","juz":6,"page":105},{"s":4,"a":176,"key":"4:176","ar":"يَسْتَفْتُونَكَ قُلِ ٱللَّهُ يُفْتِيكُمْ فِى ٱلْكَلَـٰلَةِ ۚ إِنِ ٱمْرُؤٌا۟ هَلَكَ لَيْسَ لَهُۥ وَلَدٌ وَلَهُۥٓ أُخْتٌ فَلَهَا نِصْفُ مَا تَرَكَ ۚ وَهُوَ يَرِثُهَآ إِن لَّمْ يَكُن لَّهَا وَلَدٌ ۚ فَإِن كَانَتَا ٱثْنَتَيْنِ فَلَهُمَا ٱلثُّلُثَانِ مِمَّا تَرَكَ ۚ وَإِن كَانُوٓا۟ إِخْوَةً رِّجَالًا وَنِسَآءً فَلِلذَّكَرِ مِثْلُ حَظِّ ٱلْأُنثَيَيْنِ ۗ يُبَيِّنُ ٱللَّهُ لَكُمْ أَن تَضِلُّوا۟ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۢ","en":"They request from you a [legal] ruling. Say, \"Allāh gives you a ruling concerning one having neither descendants nor ascendants [as heirs].\" If a man dies, leaving no child but [only] a sister, she will have half of what he left. And he inherits from her if she [dies and] has no child. But if there are two sisters [or more], they will have two thirds of what he left. If there are both brothers and sisters, the male will have the share of two females. Allāh makes clear to you [His law], lest you go astray. And Allāh is Knowing of all things.","tr":"Yastaftoonaka quli Allahu yufteekumfee alkalalati ini imruon halaka laysa lahu waladun walahuokhtun falaha nisfu ma taraka wahuwayarithuha in lam yakun laha waladun fa-in kanataithnatayni falahuma aththuluthani mimmataraka wa-in kanoo ikhwatan rijalan wanisaanfaliththakari mithlu haththialonthayayni yubayyinu Allahu lakum an tadilloo wallahubikulli shay-in AAaleem","juz":6,"page":106},{"s":5,"a":1,"key":"5:1","ar":" يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَوْفُوا۟ بِٱلْعُقُودِ ۚ أُحِلَّتْ لَكُم بَهِيمَةُ ٱلْأَنْعَـٰمِ إِلَّا مَا يُتْلَىٰ عَلَيْكُمْ غَيْرَ مُحِلِّى ٱلصَّيْدِ وَأَنتُمْ حُرُمٌ ۗ إِنَّ ٱللَّهَ يَحْكُمُ مَا يُرِيدُ","en":"O you who have believed, fulfill [all] contracts.1 Lawful for you are the animals of grazing livestock except for that which is recited to you [in this Qur’ān] - hunting not being permitted while you are in the state of iḥrām.2 Indeed, Allāh ordains what He intends.","tr":"Ya ayyuha allatheena amanooawfoo bilAAuqoodi ohillat lakum baheematu al-anAAamiilla ma yutla AAalaykum ghayra muhilleeassaydi waantum hurumun inna Allahayahkumu ma yureed","juz":6,"page":106},{"s":5,"a":2,"key":"5:2","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تُحِلُّوا۟ شَعَـٰٓئِرَ ٱللَّهِ وَلَا ٱلشَّهْرَ ٱلْحَرَامَ وَلَا ٱلْهَدْىَ وَلَا ٱلْقَلَـٰٓئِدَ وَلَآ ءَآمِّينَ ٱلْبَيْتَ ٱلْحَرَامَ يَبْتَغُونَ فَضْلًا مِّن رَّبِّهِمْ وَرِضْوَٰنًا ۚ وَإِذَا حَلَلْتُمْ فَٱصْطَادُوا۟ ۚ وَلَا يَجْرِمَنَّكُمْ شَنَـَٔانُ قَوْمٍ أَن صَدُّوكُمْ عَنِ ٱلْمَسْجِدِ ٱلْحَرَامِ أَن تَعْتَدُوا۟ ۘ وَتَعَاوَنُوا۟ عَلَى ٱلْبِرِّ وَٱلتَّقْوَىٰ ۖ وَلَا تَعَاوَنُوا۟ عَلَى ٱلْإِثْمِ وَٱلْعُدْوَٰنِ ۚ وَٱتَّقُوا۟ ٱللَّهَ ۖ إِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ","en":"O you who have believed, do not violate the rites of Allāh or [the sanctity of] the sacred month or [neglect the marking of] the sacrificial animals and garlanding [them] or [violate the safety of] those coming to the Sacred House seeking bounty from their Lord and [His] approval. But when you come out of iḥrām, then [you may] hunt. And do not let the hatred of a people for having obstructed you from al-Masjid al-Ḥarām lead you to transgress. And cooperate in righteousness and piety, but do not cooperate in sin and aggression. And fear Allāh; indeed, Allāh is severe in penalty.","tr":"Ya ayyuha allatheena amanoola tuhilloo shaAAa-ira Allahi walaashshahra alharama wala alhadya walaalqala-ida wala ammeena albayta alharamayabtaghoona fadlan min rabbihim waridwananwa-itha halaltum fastadoo walayajrimannakum shanaanu qawmin an saddookum AAanialmasjidi alharami an taAAtadoo wataAAawanooAAala albirri wattaqwa wala taAAawanooAAala al-ithmi walAAudwani wattaqooAllaha inna Allaha shadeedu alAAiqab","juz":6,"page":106},{"s":5,"a":3,"key":"5:3","ar":"حُرِّمَتْ عَلَيْكُمُ ٱلْمَيْتَةُ وَٱلدَّمُ وَلَحْمُ ٱلْخِنزِيرِ وَمَآ أُهِلَّ لِغَيْرِ ٱللَّهِ بِهِۦ وَٱلْمُنْخَنِقَةُ وَٱلْمَوْقُوذَةُ وَٱلْمُتَرَدِّيَةُ وَٱلنَّطِيحَةُ وَمَآ أَكَلَ ٱلسَّبُعُ إِلَّا مَا ذَكَّيْتُمْ وَمَا ذُبِحَ عَلَى ٱلنُّصُبِ وَأَن تَسْتَقْسِمُوا۟ بِٱلْأَزْلَـٰمِ ۚ ذَٰلِكُمْ فِسْقٌ ۗ ٱلْيَوْمَ يَئِسَ ٱلَّذِينَ كَفَرُوا۟ مِن دِينِكُمْ فَلَا تَخْشَوْهُمْ وَٱخْشَوْنِ ۚ ٱلْيَوْمَ أَكْمَلْتُ لَكُمْ دِينَكُمْ وَأَتْمَمْتُ عَلَيْكُمْ نِعْمَتِى وَرَضِيتُ لَكُمُ ٱلْإِسْلَـٰمَ دِينًا ۚ فَمَنِ ٱضْطُرَّ فِى مَخْمَصَةٍ غَيْرَ مُتَجَانِفٍ لِّإِثْمٍ ۙ فَإِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"Prohibited to you are dead animals,1 blood, the flesh of swine, and that which has been dedicated to other than Allāh, and [those animals] killed by strangling or by a violent blow or by a head-long fall or by the goring of horns, and those from which a wild animal has eaten, except what you [are able to] slaughter [before its death], and those which are sacrificed on stone altars,2 and [prohibited is] that you seek decision through divining arrows. That is grave disobedience. This day those who disbelieve have despaired of [defeating] your religion; so fear them not, but fear Me. This day I have perfected for you your religion and completed My favor upon you and have approved for you Islām as religion. But whoever is forced by severe hunger with no inclination to sin - then indeed, Allāh is Forgiving and Merciful.","tr":"Hurrimat AAalaykumu almaytatu waddamuwalahmu alkhinzeeri wama ohilla lighayri Allahibihi walmunkhaniqatu walmawqoothatu walmutaraddiyatuwannateehatu wama akala assabuAAuilla ma thakkaytum wama thubihaAAala annusubi waan tastaqsimoo bil-azlamithalikum fisqun alyawma ya-isa allatheena kafaroomin deenikum fala takhshawhum wakhshawni alyawmaakmaltu lakum deenakum waatmamtu AAalaykum niAAmatee waradeetulakumu al-islama deenan famani idturra fee makhmasatinghayra mutajanifin li-ithmin fa-inna Allahaghafoorun raheem","juz":6,"page":107},{"s":5,"a":4,"key":"5:4","ar":"يَسْـَٔلُونَكَ مَاذَآ أُحِلَّ لَهُمْ ۖ قُلْ أُحِلَّ لَكُمُ ٱلطَّيِّبَـٰتُ ۙ وَمَا عَلَّمْتُم مِّنَ ٱلْجَوَارِحِ مُكَلِّبِينَ تُعَلِّمُونَهُنَّ مِمَّا عَلَّمَكُمُ ٱللَّهُ ۖ فَكُلُوا۟ مِمَّآ أَمْسَكْنَ عَلَيْكُمْ وَٱذْكُرُوا۟ ٱسْمَ ٱللَّهِ عَلَيْهِ ۖ وَٱتَّقُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ","en":"They ask you, [O Muḥammad], what has been made lawful for them. Say, \"Lawful for you are [all] good foods and [game caught by] what you have trained of hunting animals1 which you train as Allāh has taught you. So eat of what they catch for you, and mention the name of Allāh upon it, and fear Allāh.\" Indeed, Allāh is swift in account.","tr":"Yas-aloonaka matha ohilla lahumqul ohilla lakumu attayyibatu wamaAAallamtum mina aljawarihi mukallibeenatuAAallimoonahunna mimma AAallamakumu Allahufakuloo mimma amsakna AAalaykum wathkurooisma Allahi AAalayhi wattaqoo Allaha innaAllaha sareeAAu alhisab","juz":6,"page":107},{"s":5,"a":5,"key":"5:5","ar":"ٱلْيَوْمَ أُحِلَّ لَكُمُ ٱلطَّيِّبَـٰتُ ۖ وَطَعَامُ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ حِلٌّ لَّكُمْ وَطَعَامُكُمْ حِلٌّ لَّهُمْ ۖ وَٱلْمُحْصَنَـٰتُ مِنَ ٱلْمُؤْمِنَـٰتِ وَٱلْمُحْصَنَـٰتُ مِنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ مِن قَبْلِكُمْ إِذَآ ءَاتَيْتُمُوهُنَّ أُجُورَهُنَّ مُحْصِنِينَ غَيْرَ مُسَـٰفِحِينَ وَلَا مُتَّخِذِىٓ أَخْدَانٍ ۗ وَمَن يَكْفُرْ بِٱلْإِيمَـٰنِ فَقَدْ حَبِطَ عَمَلُهُۥ وَهُوَ فِى ٱلْـَٔاخِرَةِ مِنَ ٱلْخَـٰسِرِينَ","en":"This day [all] good foods have been made lawful, and the food of those who were given the Scripture is lawful for you and your food is lawful for them. And [lawful in marriage are] chaste women from among the believers and chaste women from among those who were given the Scripture before you, when you have given them their due compensation,1 desiring chastity, not unlawful sexual intercourse or taking [secret] lovers. And whoever denies the faith - his work has become worthless, and he, in the Hereafter, will be among the losers.","tr":"Alyawma ohilla lakumu attayyibatuwataAAamu allatheena ootoo alkitaba hillunlakum wataAAamukum hillun lahum walmuhsanatumina almu/minati walmuhsanatu minaallatheena ootoo alkitaba min qablikum itha ataytumoohunnaojoorahunna muhsineena ghayra musafiheenawala muttakhithee akhdanin waman yakfur bil-eemanifaqad habita AAamaluhu wahuwa fee al-akhiratimina alkhasireen","juz":6,"page":107},{"s":5,"a":6,"key":"5:6","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا قُمْتُمْ إِلَى ٱلصَّلَوٰةِ فَٱغْسِلُوا۟ وُجُوهَكُمْ وَأَيْدِيَكُمْ إِلَى ٱلْمَرَافِقِ وَٱمْسَحُوا۟ بِرُءُوسِكُمْ وَأَرْجُلَكُمْ إِلَى ٱلْكَعْبَيْنِ ۚ وَإِن كُنتُمْ جُنُبًا فَٱطَّهَّرُوا۟ ۚ وَإِن كُنتُم مَّرْضَىٰٓ أَوْ عَلَىٰ سَفَرٍ أَوْ جَآءَ أَحَدٌ مِّنكُم مِّنَ ٱلْغَآئِطِ أَوْ لَـٰمَسْتُمُ ٱلنِّسَآءَ فَلَمْ تَجِدُوا۟ مَآءً فَتَيَمَّمُوا۟ صَعِيدًا طَيِّبًا فَٱمْسَحُوا۟ بِوُجُوهِكُمْ وَأَيْدِيكُم مِّنْهُ ۚ مَا يُرِيدُ ٱللَّهُ لِيَجْعَلَ عَلَيْكُم مِّنْ حَرَجٍ وَلَـٰكِن يُرِيدُ لِيُطَهِّرَكُمْ وَلِيُتِمَّ نِعْمَتَهُۥ عَلَيْكُمْ لَعَلَّكُمْ تَشْكُرُونَ","en":"O you who have believed, when you rise to [perform] prayer, wash your faces and your forearms to the elbows and wipe over your heads and wash your feet to the ankles. And if you are in a state of janābah,1 then purify yourselves. But if you are ill or on a journey or one of you comes from the place of relieving himself or you have contacted women2 and do not find water, then seek clean earth and wipe over your faces and hands with it. Allāh does not intend to make difficulty for you, but He intends to purify you and complete His favor upon you that you may be grateful.","tr":"Ya ayyuha allatheena amanooitha qumtum ila assalati faghsiloowujoohakum waaydiyakum ila almarafiqi wamsahoobiruoosikum waarjulakum ila alkaAAbayni wa-in kuntumjunuban fattahharoo wa-in kuntum marda awAAala safarin aw jaa ahadun minkum mina algha-itiaw lamastumu annisaa falam tajidoo maanfatayammamoo saAAeedan tayyiban famsahoobiwujoohikum waaydeekum minhu ma yureedu AllahuliyajAAala AAalaykum min harajin walakin yureeduliyutahhirakum waliyutimma niAAmatahu AAalaykumlaAAallakum tashkuroon","juz":6,"page":108},{"s":5,"a":7,"key":"5:7","ar":"وَٱذْكُرُوا۟ نِعْمَةَ ٱللَّهِ عَلَيْكُمْ وَمِيثَـٰقَهُ ٱلَّذِى وَاثَقَكُم بِهِۦٓ إِذْ قُلْتُمْ سَمِعْنَا وَأَطَعْنَا ۖ وَٱتَّقُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"And remember the favor of Allāh upon you and His covenant with which He bound you when you said, \"We hear and we obey\"; and fear Allāh. Indeed, Allāh is Knowing of that within the breasts.","tr":"Wathkuroo niAAmata AllahiAAalaykum wameethaqahu allathee wathaqakumbihi ith qultum samiAAna waataAAna wattaqooAllaha inna Allaha AAaleemun bithati assudoor","juz":6,"page":108},{"s":5,"a":8,"key":"5:8","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُونُوا۟ قَوَّٰمِينَ لِلَّهِ شُهَدَآءَ بِٱلْقِسْطِ ۖ وَلَا يَجْرِمَنَّكُمْ شَنَـَٔانُ قَوْمٍ عَلَىٰٓ أَلَّا تَعْدِلُوا۟ ۚ ٱعْدِلُوا۟ هُوَ أَقْرَبُ لِلتَّقْوَىٰ ۖ وَٱتَّقُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا تَعْمَلُونَ","en":"O you who have believed, be persistently standing firm for Allāh, witnesses in justice, and do not let the hatred of a people prevent you from being just. Be just; that is nearer to righteousness. And fear Allāh; indeed, Allāh is [fully] Aware of what you do.","tr":"Ya ayyuha allatheena amanookoonoo qawwameena lillahi shuhadaa bilqistiwala yajrimannakum shanaanu qawmin AAala allataAAdiloo iAAdiloo huwa aqrabu littaqwa wattaqooAllaha inna Allaha khabeerun bima taAAmaloon","juz":6,"page":108},{"s":5,"a":9,"key":"5:9","ar":"وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ ۙ لَهُم مَّغْفِرَةٌ وَأَجْرٌ عَظِيمٌ","en":"Allāh has promised those who believe and do righteous deeds [that] for them there is forgiveness and great reward.","tr":"WaAAada Allahu allatheena amanoowaAAamiloo assalihati lahum maghfiratunwaajrun AAatheem","juz":6,"page":108},{"s":5,"a":10,"key":"5:10","ar":"وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَـٰتِنَآ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْجَحِيمِ","en":"But those who disbelieve and deny Our signs - those are the companions of Hellfire.","tr":"Wallatheena kafaroo wakaththaboobi-ayatina ola-ika as-habualjaheem","juz":6,"page":109},{"s":5,"a":11,"key":"5:11","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ إِذْ هَمَّ قَوْمٌ أَن يَبْسُطُوٓا۟ إِلَيْكُمْ أَيْدِيَهُمْ فَكَفَّ أَيْدِيَهُمْ عَنكُمْ ۖ وَٱتَّقُوا۟ ٱللَّهَ ۚ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ","en":"O you who have believed, remember the favor of Allāh upon you when a people determined to extend their hands [in aggression] against you, but He withheld their hands from you; and fear Allāh. And upon Allāh let the believers rely.","tr":"Ya ayyuha allatheena amanooothkuroo niAAmata Allahi AAalaykum ith hammaqawmun an yabsutoo ilaykum aydiyahum fakaffa aydiyahumAAankum wattaqoo Allaha waAAala Allahifalyatawakkali almu/minoon","juz":6,"page":109},{"s":5,"a":12,"key":"5:12","ar":"۞ وَلَقَدْ أَخَذَ ٱللَّهُ مِيثَـٰقَ بَنِىٓ إِسْرَٰٓءِيلَ وَبَعَثْنَا مِنْهُمُ ٱثْنَىْ عَشَرَ نَقِيبًا ۖ وَقَالَ ٱللَّهُ إِنِّى مَعَكُمْ ۖ لَئِنْ أَقَمْتُمُ ٱلصَّلَوٰةَ وَءَاتَيْتُمُ ٱلزَّكَوٰةَ وَءَامَنتُم بِرُسُلِى وَعَزَّرْتُمُوهُمْ وَأَقْرَضْتُمُ ٱللَّهَ قَرْضًا حَسَنًا لَّأُكَفِّرَنَّ عَنكُمْ سَيِّـَٔاتِكُمْ وَلَأُدْخِلَنَّكُمْ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ۚ فَمَن كَفَرَ بَعْدَ ذَٰلِكَ مِنكُمْ فَقَدْ ضَلَّ سَوَآءَ ٱلسَّبِيلِ","en":"And Allāh had already taken a covenant from the Children of Israel, and We delegated from among them twelve leaders. And Allāh said, \"I am with you. If you establish prayer and give zakāh and believe in My messengers and support them and loan Allāh a goodly loan,1 I will surely remove from you your misdeeds and admit you to gardens beneath which rivers flow. But whoever of you disbelieves after that has certainly strayed from the soundness of the way.\"","tr":"Walaqad akhatha Allahu meethaqabanee isra-eela wabaAAathna minhumu ithnay AAasharanaqeeban waqala Allahu innee maAAakum la-inaqamtumu assalata waataytumu azzakatawaamantum birusulee waAAazzartumoohum waaqradtumuAllaha qardan hasanan laokaffiranna AAankumsayyi-atikum walaodkhilannakum jannatin tajree mintahtiha al-anharu faman kafara baAAda thalikaminkum faqad dalla sawaa assabeel","juz":6,"page":109},{"s":5,"a":13,"key":"5:13","ar":"فَبِمَا نَقْضِهِم مِّيثَـٰقَهُمْ لَعَنَّـٰهُمْ وَجَعَلْنَا قُلُوبَهُمْ قَـٰسِيَةً ۖ يُحَرِّفُونَ ٱلْكَلِمَ عَن مَّوَاضِعِهِۦ ۙ وَنَسُوا۟ حَظًّا مِّمَّا ذُكِّرُوا۟ بِهِۦ ۚ وَلَا تَزَالُ تَطَّلِعُ عَلَىٰ خَآئِنَةٍ مِّنْهُمْ إِلَّا قَلِيلًا مِّنْهُمْ ۖ فَٱعْفُ عَنْهُمْ وَٱصْفَحْ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُحْسِنِينَ","en":"So for their breaking of the covenant We cursed them and made their hearts hardened. They distort words from their [proper] places [i.e., usages] and have forgotten a portion of that of which they were reminded.1 And you will still observe deceit among them, except a few of them. But pardon them and overlook [their misdeeds]. Indeed, Allāh loves the doers of good.","tr":"Fabima naqdihim meethaqahumlaAAannahum wajaAAalna quloobahum qasiyatanyuharrifoona alkalima AAan mawadiAAihi wanasoo haththanmimma thukkiroo bihi wala tazalu tattaliAAuAAala kha-inatin minhum illa qaleelan minhumfaAAfu AAanhum wasfah inna Allahayuhibbu almuhsineen","juz":6,"page":109},{"s":5,"a":14,"key":"5:14","ar":"وَمِنَ ٱلَّذِينَ قَالُوٓا۟ إِنَّا نَصَـٰرَىٰٓ أَخَذْنَا مِيثَـٰقَهُمْ فَنَسُوا۟ حَظًّا مِّمَّا ذُكِّرُوا۟ بِهِۦ فَأَغْرَيْنَا بَيْنَهُمُ ٱلْعَدَاوَةَ وَٱلْبَغْضَآءَ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ ۚ وَسَوْفَ يُنَبِّئُهُمُ ٱللَّهُ بِمَا كَانُوا۟ يَصْنَعُونَ","en":"And from those who say, \"We are Christians\" We took their covenant; but they forgot a portion of that of which they were reminded.1 So We caused among them2 animosity and hatred until the Day of Resurrection. And Allāh is going to inform them about what they used to do.","tr":"Wamina allatheena qaloo innanasara akhathna meethaqahumfanasoo haththan mimma thukkiroobihi faaghrayna baynahumu alAAadawata walbaghdaaila yawmi alqiyamati wasawfa yunabbi-ohumu Allahubima kanoo yasnaAAoon","juz":6,"page":110},{"s":5,"a":15,"key":"5:15","ar":"يَـٰٓأَهْلَ ٱلْكِتَـٰبِ قَدْ جَآءَكُمْ رَسُولُنَا يُبَيِّنُ لَكُمْ كَثِيرًا مِّمَّا كُنتُمْ تُخْفُونَ مِنَ ٱلْكِتَـٰبِ وَيَعْفُوا۟ عَن كَثِيرٍ ۚ قَدْ جَآءَكُم مِّنَ ٱللَّهِ نُورٌ وَكِتَـٰبٌ مُّبِينٌ","en":"O People of the Scripture, there has come to you Our Messenger making clear to you much of what you used to conceal of the Scripture and overlooking much.1 There has come to you from Allāh a light and a clear Book [i.e., the Qur’ān]","tr":"Ya ahla alkitabi qad jaakumrasooluna yubayyinu lakum katheeran mimma kuntumtukhfoona mina alkitabi wayaAAfoo AAan katheerin qad jaakummina Allahi noorun wakitabun mubeen","juz":6,"page":110},{"s":5,"a":16,"key":"5:16","ar":"يَهْدِى بِهِ ٱللَّهُ مَنِ ٱتَّبَعَ رِضْوَٰنَهُۥ سُبُلَ ٱلسَّلَـٰمِ وَيُخْرِجُهُم مِّنَ ٱلظُّلُمَـٰتِ إِلَى ٱلنُّورِ بِإِذْنِهِۦ وَيَهْدِيهِمْ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"By which Allāh guides those who pursue His pleasure to the ways of peace1 and brings them out from darknesses into the light, by His permission, and guides them to a straight path.","tr":"Yahdee bihi Allahu mani ittabaAAa ridwanahusubula assalami wayukhrijuhum mina aththulumatiila annoori bi-ithnihi wayahdeehim ilasiratin mustaqeem","juz":6,"page":110},{"s":5,"a":17,"key":"5:17","ar":"لَّقَدْ كَفَرَ ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ هُوَ ٱلْمَسِيحُ ٱبْنُ مَرْيَمَ ۚ قُلْ فَمَن يَمْلِكُ مِنَ ٱللَّهِ شَيْـًٔا إِنْ أَرَادَ أَن يُهْلِكَ ٱلْمَسِيحَ ٱبْنَ مَرْيَمَ وَأُمَّهُۥ وَمَن فِى ٱلْأَرْضِ جَمِيعًا ۗ وَلِلَّهِ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا ۚ يَخْلُقُ مَا يَشَآءُ ۚ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"They have certainly disbelieved who say that Allāh is Christ, the son of Mary. Say, \"Then who could prevent Allāh at all if He had intended to destroy Christ, the son of Mary, or his mother or everyone on the earth?\" And to Allāh belongs the dominion of the heavens and the earth and whatever is between them. He creates what He wills, and Allāh is over all things competent.","tr":"Laqad kafara allatheena qalooinna Allaha huwa almaseehu ibnu maryama qul famanyamliku mina Allahi shay-an in arada an yuhlikaalmaseeha ibna maryama waommahu waman fee al-ardijameeAAan walillahi mulku assamawatiwal-ardi wama baynahuma yakhluqu mayashao wallahu AAala kulli shay-inqadeer","juz":6,"page":110},{"s":5,"a":18,"key":"5:18","ar":"وَقَالَتِ ٱلْيَهُودُ وَٱلنَّصَـٰرَىٰ نَحْنُ أَبْنَـٰٓؤُا۟ ٱللَّهِ وَأَحِبَّـٰٓؤُهُۥ ۚ قُلْ فَلِمَ يُعَذِّبُكُم بِذُنُوبِكُم ۖ بَلْ أَنتُم بَشَرٌ مِّمَّنْ خَلَقَ ۚ يَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۚ وَلِلَّهِ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا ۖ وَإِلَيْهِ ٱلْمَصِيرُ","en":"But the Jews and the Christians say, \"We are the children of Allāh and His beloved.\" Say, \"Then why does He punish you for your sins?\" Rather, you are human beings from among those He has created. He forgives whom He wills, and He punishes whom He wills. And to Allāh belongs the dominion of the heavens and the earth and whatever is between them, and to Him is the [final] destination.","tr":"Waqalati alyahoodu wannasaranahnu abnao Allahi waahibbaohuqul falima yuAAaththibukum bithunoobikum bal antumbasharun mimman khalaqa yaghfiru liman yashao wayuAAaththibuman yashao walillahi mulku assamawatiwal-ardi wama baynahuma wa-ilayhialmaseer","juz":6,"page":111},{"s":5,"a":19,"key":"5:19","ar":"يَـٰٓأَهْلَ ٱلْكِتَـٰبِ قَدْ جَآءَكُمْ رَسُولُنَا يُبَيِّنُ لَكُمْ عَلَىٰ فَتْرَةٍ مِّنَ ٱلرُّسُلِ أَن تَقُولُوا۟ مَا جَآءَنَا مِنۢ بَشِيرٍ وَلَا نَذِيرٍ ۖ فَقَدْ جَآءَكُم بَشِيرٌ وَنَذِيرٌ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"O People of the Scripture, there has come to you Our Messenger to make clear to you [the religion] after a period [of suspension] of messengers, lest you say, \"There came not to us any bringer of good tidings or a warner.\" But there has come to you a bringer of good tidings and a warner. And Allāh is over all things competent.","tr":"Ya ahla alkitabi qad jaakumrasooluna yubayyinu lakum AAala fatratin mina arrusulian taqooloo ma jaana min basheerin walanatheerin faqad jaakum basheerun wanatheerunwallahu AAala kulli shay-in qadeer","juz":6,"page":111},{"s":5,"a":20,"key":"5:20","ar":"وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِۦ يَـٰقَوْمِ ٱذْكُرُوا۟ نِعْمَةَ ٱللَّهِ عَلَيْكُمْ إِذْ جَعَلَ فِيكُمْ أَنۢبِيَآءَ وَجَعَلَكُم مُّلُوكًا وَءَاتَىٰكُم مَّا لَمْ يُؤْتِ أَحَدًا مِّنَ ٱلْعَـٰلَمِينَ","en":"And [mention, O Muḥammad], when Moses said to his people, \"O my people, remember the favor of Allāh upon you when He appointed among you prophets and made you possessors1 and gave you that which He had not given anyone among the worlds.","tr":"Wa-ith qala moosaliqawmihi ya qawmi othkuroo niAAmata AllahiAAalaykum ith jaAAala feekum anbiyaa wajaAAalakummulookan waatakum ma lam yu/ti ahadanmina alAAalameen","juz":6,"page":111},{"s":5,"a":21,"key":"5:21","ar":"يَـٰقَوْمِ ٱدْخُلُوا۟ ٱلْأَرْضَ ٱلْمُقَدَّسَةَ ٱلَّتِى كَتَبَ ٱللَّهُ لَكُمْ وَلَا تَرْتَدُّوا۟ عَلَىٰٓ أَدْبَارِكُمْ فَتَنقَلِبُوا۟ خَـٰسِرِينَ","en":"O my people, enter the blessed land [i.e., Palestine] which Allāh has assigned to you and do not turn back [from fighting in Allāh's cause] and [thus] become losers.\"","tr":"Ya qawmi odkhuloo al-ardaalmuqaddasata allatee kataba Allahu lakum walatartaddoo AAala adbarikum fatanqaliboo khasireen","juz":6,"page":111},{"s":5,"a":22,"key":"5:22","ar":"قَالُوا۟ يَـٰمُوسَىٰٓ إِنَّ فِيهَا قَوْمًا جَبَّارِينَ وَإِنَّا لَن نَّدْخُلَهَا حَتَّىٰ يَخْرُجُوا۟ مِنْهَا فَإِن يَخْرُجُوا۟ مِنْهَا فَإِنَّا دَٰخِلُونَ","en":"They said, \"O Moses, indeed within it is a people of tyrannical strength, and indeed, we will never enter it until they leave it; but if they leave it, then we will enter.\"","tr":"Qaloo ya moosa innafeeha qawman jabbareena wa-inna lannadkhulaha hatta yakhrujoo minhafa-in yakhrujoo minha fa-inna dakhiloon","juz":6,"page":111},{"s":5,"a":23,"key":"5:23","ar":"قَالَ رَجُلَانِ مِنَ ٱلَّذِينَ يَخَافُونَ أَنْعَمَ ٱللَّهُ عَلَيْهِمَا ٱدْخُلُوا۟ عَلَيْهِمُ ٱلْبَابَ فَإِذَا دَخَلْتُمُوهُ فَإِنَّكُمْ غَـٰلِبُونَ ۚ وَعَلَى ٱللَّهِ فَتَوَكَّلُوٓا۟ إِن كُنتُم مُّؤْمِنِينَ","en":"Said two men from those who feared [to disobey] upon whom Allāh had bestowed favor, \"Enter upon them through the gate, for when you have entered it, you will be predominant.1 And upon Allāh rely, if you should be believers.\"","tr":"Qala rajulani mina allatheenayakhafoona anAAama Allahu AAalayhimaodkhuloo AAalayhimu albaba fa-itha dakhaltumoohufa-innakum ghaliboona waAAala Allahifatawakkaloo in kuntum mu/mineen","juz":6,"page":111},{"s":5,"a":24,"key":"5:24","ar":"قَالُوا۟ يَـٰمُوسَىٰٓ إِنَّا لَن نَّدْخُلَهَآ أَبَدًا مَّا دَامُوا۟ فِيهَا ۖ فَٱذْهَبْ أَنتَ وَرَبُّكَ فَقَـٰتِلَآ إِنَّا هَـٰهُنَا قَـٰعِدُونَ","en":"They said, \"O Moses, indeed we will not enter it, ever, as long as they are within it; so go, you and your Lord, and fight. Indeed, we are remaining right here.\"","tr":"Qaloo ya moosa innalan nadkhulaha abadan ma damoo feehafa-ithhab anta warabbuka faqatila innahahuna qaAAidoon","juz":6,"page":112},{"s":5,"a":25,"key":"5:25","ar":"قَالَ رَبِّ إِنِّى لَآ أَمْلِكُ إِلَّا نَفْسِى وَأَخِى ۖ فَٱفْرُقْ بَيْنَنَا وَبَيْنَ ٱلْقَوْمِ ٱلْفَـٰسِقِينَ","en":"[Moses] said, \"My Lord, indeed I do not possess [i.e., control] except myself and my brother, so part us1 from the defiantly disobedient people.\"","tr":"Qala rabbi innee la amliku illanafsee waakhee fafruq baynana wabayna alqawmi alfasiqeen","juz":6,"page":112},{"s":5,"a":26,"key":"5:26","ar":"قَالَ فَإِنَّهَا مُحَرَّمَةٌ عَلَيْهِمْ ۛ أَرْبَعِينَ سَنَةً ۛ يَتِيهُونَ فِى ٱلْأَرْضِ ۚ فَلَا تَأْسَ عَلَى ٱلْقَوْمِ ٱلْفَـٰسِقِينَ","en":"[Allāh] said, \"Then indeed, it is forbidden to them for forty years [in which] they will wander throughout the land. So do not grieve over the defiantly disobedient people.\"","tr":"Qala fa-innaha muharramatunAAalayhim arbaAAeena sanatan yateehoona fee al-ardi falata/sa AAala alqawmi alfasiqeen","juz":6,"page":112},{"s":5,"a":27,"key":"5:27","ar":"۞ وَٱتْلُ عَلَيْهِمْ نَبَأَ ٱبْنَىْ ءَادَمَ بِٱلْحَقِّ إِذْ قَرَّبَا قُرْبَانًا فَتُقُبِّلَ مِنْ أَحَدِهِمَا وَلَمْ يُتَقَبَّلْ مِنَ ٱلْـَٔاخَرِ قَالَ لَأَقْتُلَنَّكَ ۖ قَالَ إِنَّمَا يَتَقَبَّلُ ٱللَّهُ مِنَ ٱلْمُتَّقِينَ","en":"And recite to them the story of Adam's two sons, in truth, when they both made an offering [to Allāh], and it was accepted from one of them but was not accepted from the other. Said [the latter], \"I will surely kill you.\" Said [the former], \"Indeed, Allāh only accepts from the righteous [who fear Him].","tr":"Watlu AAalayhim nabaa ibnay adamabilhaqqi ith qarraba qurbananfatuqubbila min ahadihima walam yutaqabbal mina al-akhariqala laaqtulannaka qala innama yataqabbaluAllahu mina almuttaqeen","juz":6,"page":112},{"s":5,"a":28,"key":"5:28","ar":"لَئِنۢ بَسَطتَ إِلَىَّ يَدَكَ لِتَقْتُلَنِى مَآ أَنَا۠ بِبَاسِطٍ يَدِىَ إِلَيْكَ لِأَقْتُلَكَ ۖ إِنِّىٓ أَخَافُ ٱللَّهَ رَبَّ ٱلْعَـٰلَمِينَ","en":"If you should raise your hand toward me to kill me - I shall not raise my hand toward you to kill you. Indeed, I fear Allāh, Lord of the worlds.","tr":"La-in basatta ilayya yadakalitaqtulanee ma ana bibasitin yadiyailayka li-aqtulaka innee akhafu Allaha rabba alAAalameen","juz":6,"page":112},{"s":5,"a":29,"key":"5:29","ar":"إِنِّىٓ أُرِيدُ أَن تَبُوٓأَ بِإِثْمِى وَإِثْمِكَ فَتَكُونَ مِنْ أَصْحَـٰبِ ٱلنَّارِ ۚ وَذَٰلِكَ جَزَٰٓؤُا۟ ٱلظَّـٰلِمِينَ","en":"Indeed, I want you to obtain [thereby] my sin and your sin so you will be among the companions of the Fire. And that is the recompense of wrongdoers.\"","tr":"Innee oreedu an taboo-a bi-ithmee wa-ithmikafatakoona min as-habi annari wathalikajazao aththalimeen","juz":6,"page":112},{"s":5,"a":30,"key":"5:30","ar":"فَطَوَّعَتْ لَهُۥ نَفْسُهُۥ قَتْلَ أَخِيهِ فَقَتَلَهُۥ فَأَصْبَحَ مِنَ ٱلْخَـٰسِرِينَ","en":"And his soul permitted to him1 the murder of his brother, so he killed him and became among the losers.","tr":"FatawwaAAat lahu nafsuhu qatlaakheehi faqatalahu faasbaha mina alkhasireen","juz":6,"page":112},{"s":5,"a":31,"key":"5:31","ar":"فَبَعَثَ ٱللَّهُ غُرَابًا يَبْحَثُ فِى ٱلْأَرْضِ لِيُرِيَهُۥ كَيْفَ يُوَٰرِى سَوْءَةَ أَخِيهِ ۚ قَالَ يَـٰوَيْلَتَىٰٓ أَعَجَزْتُ أَنْ أَكُونَ مِثْلَ هَـٰذَا ٱلْغُرَابِ فَأُوَٰرِىَ سَوْءَةَ أَخِى ۖ فَأَصْبَحَ مِنَ ٱلنَّـٰدِمِينَ","en":"Then Allāh sent a crow searching [i.e., scratching] in the ground to show him how to hide the disgrace1 of his brother. He said, \"O woe to me! Have I failed to be like this crow and hide the disgrace [i.e., body] of my brother?\" And he became of the regretful.","tr":"FabaAAatha Allahu ghuraban yabhathufee al-ardi liyuriyahu kayfa yuwaree saw-ataakheehi qala ya waylata aAAajaztu an akoonamithla hatha alghurabi faowariya saw-ataakhee faasbaha mina annadimeen","juz":6,"page":112},{"s":5,"a":32,"key":"5:32","ar":"مِنْ أَجْلِ ذَٰلِكَ كَتَبْنَا عَلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ أَنَّهُۥ مَن قَتَلَ نَفْسًۢا بِغَيْرِ نَفْسٍ أَوْ فَسَادٍ فِى ٱلْأَرْضِ فَكَأَنَّمَا قَتَلَ ٱلنَّاسَ جَمِيعًا وَمَنْ أَحْيَاهَا فَكَأَنَّمَآ أَحْيَا ٱلنَّاسَ جَمِيعًا ۚ وَلَقَدْ جَآءَتْهُمْ رُسُلُنَا بِٱلْبَيِّنَـٰتِ ثُمَّ إِنَّ كَثِيرًا مِّنْهُم بَعْدَ ذَٰلِكَ فِى ٱلْأَرْضِ لَمُسْرِفُونَ","en":"Because of that, We decreed upon the Children of Israel that whoever kills a soul unless for a soul1 or for corruption [done] in the land2 - it is as if he had slain mankind entirely. And whoever saves one3 - it is as if he had saved mankind entirely. And Our messengers had certainly come to them with clear proofs. Then indeed many of them, [even] after that, throughout the land, were transgressors.4","tr":"Min ajli thalika katabna AAalabanee isra-eela annahu man qatala nafsan bighayri nafsinaw fasadin fee al-ardi fakaannama qatala annasajameeAAan waman ahyaha fakaannama ahyaannasa jameeAAan walaqad jaat-hum rusulunabilbayyinati thumma inna katheeran minhum baAAda thalikafee al-ardi lamusrifoon","juz":6,"page":113},{"s":5,"a":33,"key":"5:33","ar":"إِنَّمَا جَزَٰٓؤُا۟ ٱلَّذِينَ يُحَارِبُونَ ٱللَّهَ وَرَسُولَهُۥ وَيَسْعَوْنَ فِى ٱلْأَرْضِ فَسَادًا أَن يُقَتَّلُوٓا۟ أَوْ يُصَلَّبُوٓا۟ أَوْ تُقَطَّعَ أَيْدِيهِمْ وَأَرْجُلُهُم مِّنْ خِلَـٰفٍ أَوْ يُنفَوْا۟ مِنَ ٱلْأَرْضِ ۚ ذَٰلِكَ لَهُمْ خِزْىٌ فِى ٱلدُّنْيَا ۖ وَلَهُمْ فِى ٱلْـَٔاخِرَةِ عَذَابٌ عَظِيمٌ","en":"Indeed, the penalty1 for those who wage war2 against Allāh and His Messenger and strive upon earth [to cause] corruption is none but that they be killed or crucified or that their hands and feet be cut off from opposite sides or that they be exiled from the land. That is for them a disgrace in this world; and for them in the Hereafter is a great punishment,","tr":"Innama jazao allatheenayuhariboona Allaha warasoolahu wayasAAawna feeal-ardi fasadan an yuqattaloo aw yusallabooaw tuqattaAAa aydeehim waarjuluhum min khilafin awyunfaw mina al-ardi thalika lahum khizyun fee addunyawalahum fee al-akhirati AAathabun AAatheem","juz":6,"page":113},{"s":5,"a":34,"key":"5:34","ar":"إِلَّا ٱلَّذِينَ تَابُوا۟ مِن قَبْلِ أَن تَقْدِرُوا۟ عَلَيْهِمْ ۖ فَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"Except for those who return [repenting] before you overcome [i.e., apprehend] them. And know that Allāh is Forgiving and Merciful.","tr":"Illa allatheena taboomin qabli an taqdiroo AAalayhim faAAlamoo anna Allahaghafoorun raheem","juz":6,"page":113},{"s":5,"a":35,"key":"5:35","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَٱبْتَغُوٓا۟ إِلَيْهِ ٱلْوَسِيلَةَ وَجَـٰهِدُوا۟ فِى سَبِيلِهِۦ لَعَلَّكُمْ تُفْلِحُونَ","en":"O you who have believed, fear Allāh and seek the means [of nearness] to Him and strive in His cause that you may succeed.","tr":"Ya ayyuha allatheena amanooittaqoo Allaha wabtaghoo ilayhi alwaseelata wajahidoofee sabeelihi laAAallakum tuflihoon","juz":6,"page":113},{"s":5,"a":36,"key":"5:36","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ لَوْ أَنَّ لَهُم مَّا فِى ٱلْأَرْضِ جَمِيعًا وَمِثْلَهُۥ مَعَهُۥ لِيَفْتَدُوا۟ بِهِۦ مِنْ عَذَابِ يَوْمِ ٱلْقِيَـٰمَةِ مَا تُقُبِّلَ مِنْهُمْ ۖ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"Indeed, those who disbelieve - if they should have all that is in the earth and the like of it with it by which to ransom themselves from the punishment of the Day of Resurrection, it will not be accepted from them, and for them is a painful punishment.","tr":"Inna allatheena kafaroo law annalahum ma fee al-ardi jameeAAan wamithlahu maAAahuliyaftadoo bihi min AAathabi yawmi alqiyamati matuqubbila minhum walahum AAathabun aleem","juz":6,"page":113},{"s":5,"a":37,"key":"5:37","ar":"يُرِيدُونَ أَن يَخْرُجُوا۟ مِنَ ٱلنَّارِ وَمَا هُم بِخَـٰرِجِينَ مِنْهَا ۖ وَلَهُمْ عَذَابٌ مُّقِيمٌ","en":"They will wish to get out of the Fire, but never are they to emerge therefrom, and for them is an enduring punishment.","tr":"Yureedoona an yakhrujoo mina annariwama hum bikharijeena minha walahum AAathabunmuqeem","juz":6,"page":114},{"s":5,"a":38,"key":"5:38","ar":"وَٱلسَّارِقُ وَٱلسَّارِقَةُ فَٱقْطَعُوٓا۟ أَيْدِيَهُمَا جَزَآءًۢ بِمَا كَسَبَا نَكَـٰلًا مِّنَ ٱللَّهِ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ","en":"[As for] the thief, the male and the female, amputate their hands in recompense for what they earned [i.e., committed] as a deterrent [punishment] from Allāh. And Allāh is Exalted in Might and Wise.","tr":"Wassariqu wassariqatufaqtaAAoo aydiyahuma jazaan bimakasaba nakalan mina Allahi wallahuAAazeezun hakeem","juz":6,"page":114},{"s":5,"a":39,"key":"5:39","ar":"فَمَن تَابَ مِنۢ بَعْدِ ظُلْمِهِۦ وَأَصْلَحَ فَإِنَّ ٱللَّهَ يَتُوبُ عَلَيْهِ ۗ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"But whoever repents after his wrongdoing and reforms, indeed, Allāh will turn to him in forgiveness. Indeed, Allāh is Forgiving and Merciful.","tr":"Faman taba min baAAdi thulmihiwaaslaha fa-inna Allaha yatoobu AAalayhiinna Allaha ghafoorun raheem","juz":6,"page":114},{"s":5,"a":40,"key":"5:40","ar":"أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ لَهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ يُعَذِّبُ مَن يَشَآءُ وَيَغْفِرُ لِمَن يَشَآءُ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Do you not know that to Allāh belongs the dominion of the heavens and the earth? He punishes whom He wills and forgives whom He wills, and Allāh is over all things competent.","tr":"Alam taAAlam anna Allaha lahu mulku assamawatiwal-ardi yuAAaththibu man yashaowayaghfiru liman yashao wallahu AAalakulli shay-in qadeer","juz":6,"page":114},{"s":5,"a":41,"key":"5:41","ar":"۞ يَـٰٓأَيُّهَا ٱلرَّسُولُ لَا يَحْزُنكَ ٱلَّذِينَ يُسَـٰرِعُونَ فِى ٱلْكُفْرِ مِنَ ٱلَّذِينَ قَالُوٓا۟ ءَامَنَّا بِأَفْوَٰهِهِمْ وَلَمْ تُؤْمِن قُلُوبُهُمْ ۛ وَمِنَ ٱلَّذِينَ هَادُوا۟ ۛ سَمَّـٰعُونَ لِلْكَذِبِ سَمَّـٰعُونَ لِقَوْمٍ ءَاخَرِينَ لَمْ يَأْتُوكَ ۖ يُحَرِّفُونَ ٱلْكَلِمَ مِنۢ بَعْدِ مَوَاضِعِهِۦ ۖ يَقُولُونَ إِنْ أُوتِيتُمْ هَـٰذَا فَخُذُوهُ وَإِن لَّمْ تُؤْتَوْهُ فَٱحْذَرُوا۟ ۚ وَمَن يُرِدِ ٱللَّهُ فِتْنَتَهُۥ فَلَن تَمْلِكَ لَهُۥ مِنَ ٱللَّهِ شَيْـًٔا ۚ أُو۟لَـٰٓئِكَ ٱلَّذِينَ لَمْ يُرِدِ ٱللَّهُ أَن يُطَهِّرَ قُلُوبَهُمْ ۚ لَهُمْ فِى ٱلدُّنْيَا خِزْىٌ ۖ وَلَهُمْ فِى ٱلْـَٔاخِرَةِ عَذَابٌ عَظِيمٌ","en":"O Messenger, let them not grieve you who hasten into disbelief of those who say, \"We believe\" with their mouths, but their hearts believe not, and from among the Jews. [They are] avid listeners to falsehood, listening to another people who have not come to you.1 They distort words beyond their [proper] places [i.e., usages], saying, \"If you are given this,2 take it; but if you are not given it, then beware.\" But he for whom Allāh intends fitnah3 - never will you possess [power to do] for him a thing against Allāh. Those are the ones for whom Allāh does not intend to purify their hearts. For them in this world is disgrace, and for them in the Hereafter is a great punishment.","tr":"Ya ayyuha arrasoolu layahzunka allatheena yusariAAoona fee alkufrimina allatheena qaloo amanna bi-afwahihimwalam tu/min quloobuhum wamina allatheena hadoosammaAAoona lilkathibi sammaAAoona liqawmin akhareenalam ya/tooka yuharrifoona alkalima min baAAdi mawadiAAihiyaqooloona in ooteetum hatha fakhuthoohu wa-in lamtu/tawhu fahtharoo waman yuridi Allahufitnatahu falan tamlika lahu mina Allahi shay-an ola-ikaallatheena lam yuridi Allahu an yutahhiraquloobahum lahum fee addunya khizyun walahum feeal-akhirati AAathabun AAatheem","juz":6,"page":114},{"s":5,"a":42,"key":"5:42","ar":"سَمَّـٰعُونَ لِلْكَذِبِ أَكَّـٰلُونَ لِلسُّحْتِ ۚ فَإِن جَآءُوكَ فَٱحْكُم بَيْنَهُمْ أَوْ أَعْرِضْ عَنْهُمْ ۖ وَإِن تُعْرِضْ عَنْهُمْ فَلَن يَضُرُّوكَ شَيْـًٔا ۖ وَإِنْ حَكَمْتَ فَٱحْكُم بَيْنَهُم بِٱلْقِسْطِ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُقْسِطِينَ","en":"[They are] avid listeners to falsehood, devourers of [what is] unlawful. So if they come to you, [O Muḥammad], judge between them or turn away from them. And if you turn away from them - never will they harm you at all. And if you judge, judge between them with justice. Indeed, Allāh loves those who act justly.","tr":"SammaAAoona lilkathibi akkaloonalissuhti fa-in jaooka fahkumbaynahum aw aAArid AAanhum wa-in tuAArid AAanhumfalan yadurrooka shay-an wa-in hakamta fahkumbaynahum bilqisti inna Allaha yuhibbualmuqsiteen","juz":6,"page":115},{"s":5,"a":43,"key":"5:43","ar":"وَكَيْفَ يُحَكِّمُونَكَ وَعِندَهُمُ ٱلتَّوْرَىٰةُ فِيهَا حُكْمُ ٱللَّهِ ثُمَّ يَتَوَلَّوْنَ مِنۢ بَعْدِ ذَٰلِكَ ۚ وَمَآ أُو۟لَـٰٓئِكَ بِٱلْمُؤْمِنِينَ","en":"But how is it that they come to you for judgement while they have the Torah, in which is the judgement of Allāh? Then they turn away, [even] after that; but those are not [in fact] believers.","tr":"Wakayfa yuhakkimoonaka waAAindahumu attawratufeeha hukmu Allahi thumma yatawallawna minbaAAdi thalika wama ola-ika bilmu/mineen","juz":6,"page":115},{"s":5,"a":44,"key":"5:44","ar":"إِنَّآ أَنزَلْنَا ٱلتَّوْرَىٰةَ فِيهَا هُدًى وَنُورٌ ۚ يَحْكُمُ بِهَا ٱلنَّبِيُّونَ ٱلَّذِينَ أَسْلَمُوا۟ لِلَّذِينَ هَادُوا۟ وَٱلرَّبَّـٰنِيُّونَ وَٱلْأَحْبَارُ بِمَا ٱسْتُحْفِظُوا۟ مِن كِتَـٰبِ ٱللَّهِ وَكَانُوا۟ عَلَيْهِ شُهَدَآءَ ۚ فَلَا تَخْشَوُا۟ ٱلنَّاسَ وَٱخْشَوْنِ وَلَا تَشْتَرُوا۟ بِـَٔايَـٰتِى ثَمَنًا قَلِيلًا ۚ وَمَن لَّمْ يَحْكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْكَـٰفِرُونَ","en":"Indeed, We sent down the Torah, in which was guidance and light. The prophets who submitted [to Allāh] judged by it for the Jews, as did the rabbis and scholars by that with which they were entrusted of the Scripture of Allāh, and they were witnesses thereto. So do not fear the people but fear Me, and do not exchange My verses for a small price [i.e., worldly gain]. And whoever does not judge by what Allāh has revealed - then it is those who are the disbelievers.","tr":"Inna anzalna attawratafeeha hudan wanoorun yahkumu biha annabiyyoonaallatheena aslamoo lillatheena hadoo warrabbaniyyoonawal-ahbaru bima istuhfithoomin kitabi Allahi wakanoo AAalayhi shuhadaafala takhshawoo annasa wakhshawniwala tashtaroo bi-ayatee thamanan qaleelanwaman lam yahkum bima anzala Allahu faola-ikahumu alkafiroon","juz":6,"page":115},{"s":5,"a":45,"key":"5:45","ar":"وَكَتَبْنَا عَلَيْهِمْ فِيهَآ أَنَّ ٱلنَّفْسَ بِٱلنَّفْسِ وَٱلْعَيْنَ بِٱلْعَيْنِ وَٱلْأَنفَ بِٱلْأَنفِ وَٱلْأُذُنَ بِٱلْأُذُنِ وَٱلسِّنَّ بِٱلسِّنِّ وَٱلْجُرُوحَ قِصَاصٌ ۚ فَمَن تَصَدَّقَ بِهِۦ فَهُوَ كَفَّارَةٌ لَّهُۥ ۚ وَمَن لَّمْ يَحْكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُو۟لَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ","en":"And We ordained for them therein a life for a life, an eye for an eye, a nose for a nose, an ear for an ear, a tooth for a tooth, and for wounds is legal retribution. But whoever gives [up his right as] charity, it is an expiation for him. And whoever does not judge by what Allāh has revealed - then it is those who are the wrongdoers [i.e., the unjust].","tr":"Wakatabna AAalayhim feeha annaannafsa binnafsi walAAayna bilAAayniwal-anfa bil-anfi walothuna bilothuniwassinna bissinni waljurooha qisasunfaman tasaddaqa bihi fahuwa kaffaratun lahu wamanlam yahkum bima anzala Allahu faola-ikahumu aththalimoon","juz":6,"page":115},{"s":5,"a":46,"key":"5:46","ar":"وَقَفَّيْنَا عَلَىٰٓ ءَاثَـٰرِهِم بِعِيسَى ٱبْنِ مَرْيَمَ مُصَدِّقًا لِّمَا بَيْنَ يَدَيْهِ مِنَ ٱلتَّوْرَىٰةِ ۖ وَءَاتَيْنَـٰهُ ٱلْإِنجِيلَ فِيهِ هُدًى وَنُورٌ وَمُصَدِّقًا لِّمَا بَيْنَ يَدَيْهِ مِنَ ٱلتَّوْرَىٰةِ وَهُدًى وَمَوْعِظَةً لِّلْمُتَّقِينَ","en":"And We sent, following in their footsteps,1 Jesus, the son of Mary, confirming that which came before him in the Torah; and We gave him the Gospel, in which was guidance and light and confirming that which preceded it of the Torah as guidance and instruction for the righteous.","tr":"Waqaffayna AAala atharihimbiAAeesa ibni maryama musaddiqan lima baynayadayhi mina attawrati waataynahual-injeela feehi hudan wanoorun wamusaddiqan limabayna yadayhi mina attawrati wahudan wamawAAithatanlilmuttaqeen","juz":6,"page":116},{"s":5,"a":47,"key":"5:47","ar":"وَلْيَحْكُمْ أَهْلُ ٱلْإِنجِيلِ بِمَآ أَنزَلَ ٱللَّهُ فِيهِ ۚ وَمَن لَّمْ يَحْكُم بِمَآ أَنزَلَ ٱللَّهُ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ","en":"And let the People of the Gospel judge by what Allāh has revealed therein. And whoever does not judge by what Allāh has revealed - then it is those who are the defiantly disobedient.","tr":"Walyahkum ahlu al-injeeli bimaanzala Allahu feehi waman lam yahkum bimaanzala Allahu faola-ika humu alfasiqoon","juz":6,"page":116},{"s":5,"a":48,"key":"5:48","ar":"وَأَنزَلْنَآ إِلَيْكَ ٱلْكِتَـٰبَ بِٱلْحَقِّ مُصَدِّقًا لِّمَا بَيْنَ يَدَيْهِ مِنَ ٱلْكِتَـٰبِ وَمُهَيْمِنًا عَلَيْهِ ۖ فَٱحْكُم بَيْنَهُم بِمَآ أَنزَلَ ٱللَّهُ ۖ وَلَا تَتَّبِعْ أَهْوَآءَهُمْ عَمَّا جَآءَكَ مِنَ ٱلْحَقِّ ۚ لِكُلٍّ جَعَلْنَا مِنكُمْ شِرْعَةً وَمِنْهَاجًا ۚ وَلَوْ شَآءَ ٱللَّهُ لَجَعَلَكُمْ أُمَّةً وَٰحِدَةً وَلَـٰكِن لِّيَبْلُوَكُمْ فِى مَآ ءَاتَىٰكُمْ ۖ فَٱسْتَبِقُوا۟ ٱلْخَيْرَٰتِ ۚ إِلَى ٱللَّهِ مَرْجِعُكُمْ جَمِيعًا فَيُنَبِّئُكُم بِمَا كُنتُمْ فِيهِ تَخْتَلِفُونَ","en":"And We have revealed to you, [O Muḥammad], the Book [i.e., the Qur’ān] in truth, confirming that which preceded it of the Scripture and as a criterion over it. So judge between them by what Allāh has revealed and do not follow their inclinations away from what has come to you of the truth. To each of you We prescribed a law and a method.1 Had Allāh willed, He would have made you one nation [united in religion], but [He intended] to test you in what He has given you; so race to [all that is] good.2 To Allāh is your return all together, and He will [then] inform you concerning that over which you used to differ.","tr":"Waanzalna ilayka alkitaba bilhaqqimusaddiqan lima bayna yadayhi mina alkitabiwamuhayminan AAalayhi fahkum baynahum bimaanzala Allahu wala tattabiAA ahwaahum AAammajaaka mina alhaqqi likullin jaAAalna minkumshirAAatan waminhajan walaw shaa AllahulajaAAalakum ommatan wahidatan walakin liyabluwakumfeema atakum fastabiqoo alkhayratiila Allahi marjiAAukum jameeAAan fayunabbi-okum bimakuntum feehi takhtalifoon","juz":6,"page":116},{"s":5,"a":49,"key":"5:49","ar":"وَأَنِ ٱحْكُم بَيْنَهُم بِمَآ أَنزَلَ ٱللَّهُ وَلَا تَتَّبِعْ أَهْوَآءَهُمْ وَٱحْذَرْهُمْ أَن يَفْتِنُوكَ عَنۢ بَعْضِ مَآ أَنزَلَ ٱللَّهُ إِلَيْكَ ۖ فَإِن تَوَلَّوْا۟ فَٱعْلَمْ أَنَّمَا يُرِيدُ ٱللَّهُ أَن يُصِيبَهُم بِبَعْضِ ذُنُوبِهِمْ ۗ وَإِنَّ كَثِيرًا مِّنَ ٱلنَّاسِ لَفَـٰسِقُونَ","en":"And judge, [O Muḥammad], between them by what Allāh has revealed and do not follow their inclinations and beware of them, lest they tempt you away from some of what Allāh has revealed to you. And if they turn away - then know that Allāh only intends to afflict them with some of their [own] sins. And indeed, many among the people are defiantly disobedient.","tr":"Waani ohkum baynahum bimaanzala Allahu wala tattabiAA ahwaahum wahtharhuman yaftinooka AAan baAAdi ma anzala Allahuilayka fa-in tawallaw faAAlam annama yureedu Allahuan yuseebahum bibaAAdi thunoobihim wa-innakatheeran mina annasi lafasiqoon","juz":6,"page":116},{"s":5,"a":50,"key":"5:50","ar":"أَفَحُكْمَ ٱلْجَـٰهِلِيَّةِ يَبْغُونَ ۚ وَمَنْ أَحْسَنُ مِنَ ٱللَّهِ حُكْمًا لِّقَوْمٍ يُوقِنُونَ","en":"Then is it the judgement of [the time of] ignorance they desire? But who is better than Allāh in judgement for a people who are certain [in faith].","tr":"Afahukma aljahiliyyatiyabghoona waman ahsanu mina Allahu hukmanliqawmin yooqinoon","juz":6,"page":116},{"s":5,"a":51,"key":"5:51","ar":"۞ يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ ٱلْيَهُودَ وَٱلنَّصَـٰرَىٰٓ أَوْلِيَآءَ ۘ بَعْضُهُمْ أَوْلِيَآءُ بَعْضٍ ۚ وَمَن يَتَوَلَّهُم مِّنكُمْ فَإِنَّهُۥ مِنْهُمْ ۗ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"O you who have believed, do not take the Jews and the Christians as allies. They are [in fact] allies of one another. And whoever is an ally to them among you - then indeed, he is [one] of them. Indeed, Allāh guides not the wrongdoing people.","tr":"Ya ayyuha allatheena amanoola tattakhithoo alyahooda wannasaraawliyaa baAAduhum awliyao baAAdinwaman yatawallahum minkum fa-innahu minhum inna Allaha layahdee alqawma aththalimeen","juz":6,"page":117},{"s":5,"a":52,"key":"5:52","ar":"فَتَرَى ٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌ يُسَـٰرِعُونَ فِيهِمْ يَقُولُونَ نَخْشَىٰٓ أَن تُصِيبَنَا دَآئِرَةٌ ۚ فَعَسَى ٱللَّهُ أَن يَأْتِىَ بِٱلْفَتْحِ أَوْ أَمْرٍ مِّنْ عِندِهِۦ فَيُصْبِحُوا۟ عَلَىٰ مَآ أَسَرُّوا۟ فِىٓ أَنفُسِهِمْ نَـٰدِمِينَ","en":"So you see those in whose hearts is disease [i.e., hypocrisy] hastening into [association with] them, saying, \"We are afraid a misfortune may strike us.\" But perhaps Allāh will bring conquest or a decision from Him, and they will become, over what they have been concealing within themselves, regretful.","tr":"Fatara allatheena feequloobihim maradun yusariAAoona feehim yaqooloonanakhsha an tuseebana da-iratun faAAasaAllahu an ya/tiya bilfathi aw amrin minAAindihi fayusbihoo AAala ma asarroofee anfusihim nadimeen","juz":6,"page":117},{"s":5,"a":53,"key":"5:53","ar":"وَيَقُولُ ٱلَّذِينَ ءَامَنُوٓا۟ أَهَـٰٓؤُلَآءِ ٱلَّذِينَ أَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَـٰنِهِمْ ۙ إِنَّهُمْ لَمَعَكُمْ ۚ حَبِطَتْ أَعْمَـٰلُهُمْ فَأَصْبَحُوا۟ خَـٰسِرِينَ","en":"And those who believe will say,1 \"Are these the ones who swore by Allāh their strongest oaths that indeed they were with you?\" Their deeds have become worthless, and they have become losers.","tr":"Wayaqoolu allatheena amanoo ahaola-iallatheena aqsamoo billahi jahda aymanihiminnahum lamaAAakum habitat aAAmaluhum faasbahookhasireen","juz":6,"page":117},{"s":5,"a":54,"key":"5:54","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ مَن يَرْتَدَّ مِنكُمْ عَن دِينِهِۦ فَسَوْفَ يَأْتِى ٱللَّهُ بِقَوْمٍ يُحِبُّهُمْ وَيُحِبُّونَهُۥٓ أَذِلَّةٍ عَلَى ٱلْمُؤْمِنِينَ أَعِزَّةٍ عَلَى ٱلْكَـٰفِرِينَ يُجَـٰهِدُونَ فِى سَبِيلِ ٱللَّهِ وَلَا يَخَافُونَ لَوْمَةَ لَآئِمٍ ۚ ذَٰلِكَ فَضْلُ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۚ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ","en":"O you who have believed, whoever of you should revert from his religion - Allāh will bring forth [in place of them] a people He will love and who will love Him [who are] humble toward the believers, strong against the disbelievers; they strive in the cause of Allāh and do not fear the blame of a critic. That is the favor of Allāh; He bestows it upon whom He wills. And Allāh is all-Encompassing and Knowing.","tr":"Ya ayyuha allatheena amanooman yartadda minkum AAan deenihi fasawfa ya/tee Allahubiqawmin yuhibbuhum wayuhibboonahu athillatinAAala almu/mineena aAAizzatin AAala alkafireenayujahidoona fee sabeeli Allahi wala yakhafoonalawmata la-imin thalika fadlu Allahiyu/teehi man yashao wallahu wasiAAunAAaleem","juz":6,"page":117},{"s":5,"a":55,"key":"5:55","ar":"إِنَّمَا وَلِيُّكُمُ ٱللَّهُ وَرَسُولُهُۥ وَٱلَّذِينَ ءَامَنُوا۟ ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَهُمْ رَٰكِعُونَ","en":"Your ally is none but Allāh and [therefore] His Messenger and those who have believed - those who establish prayer and give zakāh, and they bow [in worship].","tr":"Innama waliyyukumu Allahuwarasooluhu wallatheena amanoo allatheenayuqeemoona assalata wayu/toona azzakatawahum rakiAAoon","juz":6,"page":117},{"s":5,"a":56,"key":"5:56","ar":"وَمَن يَتَوَلَّ ٱللَّهَ وَرَسُولَهُۥ وَٱلَّذِينَ ءَامَنُوا۟ فَإِنَّ حِزْبَ ٱللَّهِ هُمُ ٱلْغَـٰلِبُونَ","en":"And whoever is an ally of Allāh and His Messenger and those who have believed - indeed, the party of Allāh - they will be the predominant.","tr":"Waman yatawalla Allaha warasoolahu wallatheenaamanoo fa-inna hizba Allahi humu alghaliboon","juz":6,"page":117},{"s":5,"a":57,"key":"5:57","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ ٱلَّذِينَ ٱتَّخَذُوا۟ دِينَكُمْ هُزُوًا وَلَعِبًا مِّنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ مِن قَبْلِكُمْ وَٱلْكُفَّارَ أَوْلِيَآءَ ۚ وَٱتَّقُوا۟ ٱللَّهَ إِن كُنتُم مُّؤْمِنِينَ","en":"O you who have believed, take not those who have taken your religion in ridicule and amusement among the ones who were given the Scripture before you nor the disbelievers as allies. And fear Allāh, if you should [truly] be believers.","tr":"Ya ayyuha allatheena amanoola tattakhithoo allatheena ittakhathoodeenakum huzuwan walaAAiban mina allatheena ootoo alkitabamin qablikum walkuffara awliyaa wattaqooAllaha in kuntum mu/mineen","juz":6,"page":117},{"s":5,"a":58,"key":"5:58","ar":"وَإِذَا نَادَيْتُمْ إِلَى ٱلصَّلَوٰةِ ٱتَّخَذُوهَا هُزُوًا وَلَعِبًا ۚ ذَٰلِكَ بِأَنَّهُمْ قَوْمٌ لَّا يَعْقِلُونَ","en":"And when you call to prayer, they take it in ridicule and amusement. That is because they are a people who do not use reason.","tr":"Wa-itha nadaytum ila assalatiittakhathooha huzuwan walaAAiban thalikabi-annahum qawmun la yaAAqiloon","juz":6,"page":118},{"s":5,"a":59,"key":"5:59","ar":"قُلْ يَـٰٓأَهْلَ ٱلْكِتَـٰبِ هَلْ تَنقِمُونَ مِنَّآ إِلَّآ أَنْ ءَامَنَّا بِٱللَّهِ وَمَآ أُنزِلَ إِلَيْنَا وَمَآ أُنزِلَ مِن قَبْلُ وَأَنَّ أَكْثَرَكُمْ فَـٰسِقُونَ","en":"Say, \"O People of the Scripture, do you resent us except [for the fact] that we have believed in Allāh and what was revealed to us and what was revealed before and because most of you are defiantly disobedient?\"","tr":"Qul ya ahla alkitabi haltanqimoona minna illa an amanna billahiwama onzila ilayna wama onzila min qabluwaanna aktharakum fasiqoon","juz":6,"page":118},{"s":5,"a":60,"key":"5:60","ar":"قُلْ هَلْ أُنَبِّئُكُم بِشَرٍّ مِّن ذَٰلِكَ مَثُوبَةً عِندَ ٱللَّهِ ۚ مَن لَّعَنَهُ ٱللَّهُ وَغَضِبَ عَلَيْهِ وَجَعَلَ مِنْهُمُ ٱلْقِرَدَةَ وَٱلْخَنَازِيرَ وَعَبَدَ ٱلطَّـٰغُوتَ ۚ أُو۟لَـٰٓئِكَ شَرٌّ مَّكَانًا وَأَضَلُّ عَن سَوَآءِ ٱلسَّبِيلِ","en":"Say, \"Shall I inform you of [what is] worse than that1 as penalty from Allāh? [It is that of] those whom Allāh has cursed and with whom He became angry and made of them apes and pigs and slaves of ṭāghūt.2 Those are worse in position and further astray from the sound way.\"","tr":"Qul hal onabbi-okum bisharrin min thalikamathoobatan AAinda Allahi man laAAanahu Allahuwaghadiba AAalayhi wajaAAala minhumu alqiradata walkhanazeerawaAAabada attaghooti ola-ika sharrun makananwaadallu AAan sawa-i assabeel","juz":6,"page":118},{"s":5,"a":61,"key":"5:61","ar":"وَإِذَا جَآءُوكُمْ قَالُوٓا۟ ءَامَنَّا وَقَد دَّخَلُوا۟ بِٱلْكُفْرِ وَهُمْ قَدْ خَرَجُوا۟ بِهِۦ ۚ وَٱللَّهُ أَعْلَمُ بِمَا كَانُوا۟ يَكْتُمُونَ","en":"And when they come to you, they say, \"We believe.\" But they have entered with disbelief [in their hearts], and they have certainly left with it. And Allāh is most knowing of what they were concealing.","tr":"Wa-itha jaookum qaloo amannawaqad dakhaloo bilkufri wahum qad kharajoo bihi wallahuaAAlamu bima kanoo yaktumoon","juz":6,"page":118},{"s":5,"a":62,"key":"5:62","ar":"وَتَرَىٰ كَثِيرًا مِّنْهُمْ يُسَـٰرِعُونَ فِى ٱلْإِثْمِ وَٱلْعُدْوَٰنِ وَأَكْلِهِمُ ٱلسُّحْتَ ۚ لَبِئْسَ مَا كَانُوا۟ يَعْمَلُونَ","en":"And you see many of them hastening into sin and aggression and the devouring of [what is] unlawful. How wretched is what they have been doing.","tr":"Watara katheeran minhum yusariAAoonafee al-ithmi walAAudwani waaklihimu assuhtalabi/sa ma kanoo yaAAmaloon","juz":6,"page":118},{"s":5,"a":63,"key":"5:63","ar":"لَوْلَا يَنْهَىٰهُمُ ٱلرَّبَّـٰنِيُّونَ وَٱلْأَحْبَارُ عَن قَوْلِهِمُ ٱلْإِثْمَ وَأَكْلِهِمُ ٱلسُّحْتَ ۚ لَبِئْسَ مَا كَانُوا۟ يَصْنَعُونَ","en":"Why do the rabbis and religious scholars not forbid them from saying what is sinful and devouring what is unlawful? How wretched is what they have been practicing.","tr":"Lawla yanhahumu arrabbaniyyoonawal-ahbaru AAan qawlihimu al-ithmawaaklihimu assuhta labi/sa ma kanooyasnaAAoon","juz":6,"page":118},{"s":5,"a":64,"key":"5:64","ar":"وَقَالَتِ ٱلْيَهُودُ يَدُ ٱللَّهِ مَغْلُولَةٌ ۚ غُلَّتْ أَيْدِيهِمْ وَلُعِنُوا۟ بِمَا قَالُوا۟ ۘ بَلْ يَدَاهُ مَبْسُوطَتَانِ يُنفِقُ كَيْفَ يَشَآءُ ۚ وَلَيَزِيدَنَّ كَثِيرًا مِّنْهُم مَّآ أُنزِلَ إِلَيْكَ مِن رَّبِّكَ طُغْيَـٰنًا وَكُفْرًا ۚ وَأَلْقَيْنَا بَيْنَهُمُ ٱلْعَدَٰوَةَ وَٱلْبَغْضَآءَ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ ۚ كُلَّمَآ أَوْقَدُوا۟ نَارًا لِّلْحَرْبِ أَطْفَأَهَا ٱللَّهُ ۚ وَيَسْعَوْنَ فِى ٱلْأَرْضِ فَسَادًا ۚ وَٱللَّهُ لَا يُحِبُّ ٱلْمُفْسِدِينَ","en":"And the Jews say, \"The hand of Allāh is chained.\"1 Chained are their hands, and cursed are they for what they say. Rather, both His hands are extended; He spends however He wills. And that which has been revealed to you from your Lord will surely increase many of them in transgression and disbelief. And We have cast among them animosity and hatred until the Day of Resurrection. Every time they kindled the fire of war [against you], Allāh extinguished it. And they strive throughout the land [causing] corruption, and Allāh does not like corrupters.","tr":"Waqalati alyahoodu yadu Allahimaghloolatun ghullat aydeehim waluAAinoo bima qaloobal yadahu mabsootatani yunfiqu kayfa yashaowalayazeedanna katheeran minhum ma onzila ilayka minrabbika tughyanan wakufran waalqaynabaynahumu alAAadawata walbaghdaa ilayawmi alqiyamati kullama awqadoo naran lilharbiatfaaha Allahu wayasAAawna fee al-ardifasadan wallahu la yuhibbualmufsideen","juz":6,"page":118},{"s":5,"a":65,"key":"5:65","ar":"وَلَوْ أَنَّ أَهْلَ ٱلْكِتَـٰبِ ءَامَنُوا۟ وَٱتَّقَوْا۟ لَكَفَّرْنَا عَنْهُمْ سَيِّـَٔاتِهِمْ وَلَأَدْخَلْنَـٰهُمْ جَنَّـٰتِ ٱلنَّعِيمِ","en":"And if only the People of the Scripture had believed and feared Allāh, We would have removed from them their misdeeds and admitted them to Gardens of Pleasure.","tr":"Walaw anna ahla alkitabi amanoowattaqaw lakaffarna AAanhum sayyi-atihimwalaadkhalnahum jannati annaAAeem","juz":6,"page":119},{"s":5,"a":66,"key":"5:66","ar":"وَلَوْ أَنَّهُمْ أَقَامُوا۟ ٱلتَّوْرَىٰةَ وَٱلْإِنجِيلَ وَمَآ أُنزِلَ إِلَيْهِم مِّن رَّبِّهِمْ لَأَكَلُوا۟ مِن فَوْقِهِمْ وَمِن تَحْتِ أَرْجُلِهِم ۚ مِّنْهُمْ أُمَّةٌ مُّقْتَصِدَةٌ ۖ وَكَثِيرٌ مِّنْهُمْ سَآءَ مَا يَعْمَلُونَ","en":"And if only they had upheld [the law of] the Torah, the Gospel, and what has been revealed to them from their Lord [i.e., the Qur’ān], they would have consumed [provision] from above them and from beneath their feet.1 Among them are a moderate [i.e., acceptable] community, but many of them - evil is that which they do.","tr":"Walaw annahum aqamoo attawratawal-injeela wama onzila ilayhim min rabbihimlaakaloo min fawqihim wamin tahti arjulihim minhum ommatunmuqtasidatun wakatheerun minhum saa mayaAAmaloon","juz":6,"page":119},{"s":5,"a":67,"key":"5:67","ar":"۞ يَـٰٓأَيُّهَا ٱلرَّسُولُ بَلِّغْ مَآ أُنزِلَ إِلَيْكَ مِن رَّبِّكَ ۖ وَإِن لَّمْ تَفْعَلْ فَمَا بَلَّغْتَ رِسَالَتَهُۥ ۚ وَٱللَّهُ يَعْصِمُكَ مِنَ ٱلنَّاسِ ۗ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلْكَـٰفِرِينَ","en":"O Messenger, announce that which has been revealed to you from your Lord, and if you do not, then you have not conveyed His message. And Allāh will protect you from the people. Indeed, Allāh does not guide the disbelieving people.","tr":"Ya ayyuha arrasooluballigh ma onzila ilayka min rabbika wa-in lam tafAAal famaballaghta risalatahu wallahu yaAAsimukamina annasi inna Allaha la yahdeealqawma alkafireen","juz":6,"page":119},{"s":5,"a":68,"key":"5:68","ar":"قُلْ يَـٰٓأَهْلَ ٱلْكِتَـٰبِ لَسْتُمْ عَلَىٰ شَىْءٍ حَتَّىٰ تُقِيمُوا۟ ٱلتَّوْرَىٰةَ وَٱلْإِنجِيلَ وَمَآ أُنزِلَ إِلَيْكُم مِّن رَّبِّكُمْ ۗ وَلَيَزِيدَنَّ كَثِيرًا مِّنْهُم مَّآ أُنزِلَ إِلَيْكَ مِن رَّبِّكَ طُغْيَـٰنًا وَكُفْرًا ۖ فَلَا تَأْسَ عَلَى ٱلْقَوْمِ ٱلْكَـٰفِرِينَ","en":"Say, \"O People of the Scripture, you are [standing] on nothing until you uphold [the law of] the Torah, the Gospel, and what has been revealed to you from your Lord [i.e., the Qur’ān].\" And that which has been revealed to you from your Lord will surely increase many of them in transgression and disbelief. So do not grieve over the disbelieving people.","tr":"Qul ya ahla alkitabi lastumAAala shay-in hatta tuqeemoo attawratawal-injeela wama onzila ilaykum min rabbikumwalayazeedanna katheeran minhum ma onzila ilayka minrabbika tughyanan wakufran fala ta/sa AAalaalqawmi alkafireen","juz":6,"page":119},{"s":5,"a":69,"key":"5:69","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَادُوا۟ وَٱلصَّـٰبِـُٔونَ وَٱلنَّصَـٰرَىٰ مَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ وَعَمِلَ صَـٰلِحًا فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"Indeed, those who have believed [in Prophet Muḥammad (ﷺ)] and those [before him (ﷺ)] who were Jews or Sabeans or Christians - those [among them] who believed in Allāh and the Last Day and did righteousness - no fear will there be concerning them, nor will they grieve.1","tr":"Inna allatheena amanoo wallatheenahadoo wassabi-oona wannasaraman amana billahi walyawmi al-akhiriwaAAamila salihan fala khawfun AAalayhim walahum yahzanoon","juz":6,"page":119},{"s":5,"a":70,"key":"5:70","ar":"لَقَدْ أَخَذْنَا مِيثَـٰقَ بَنِىٓ إِسْرَٰٓءِيلَ وَأَرْسَلْنَآ إِلَيْهِمْ رُسُلًا ۖ كُلَّمَا جَآءَهُمْ رَسُولٌۢ بِمَا لَا تَهْوَىٰٓ أَنفُسُهُمْ فَرِيقًا كَذَّبُوا۟ وَفَرِيقًا يَقْتُلُونَ","en":"We had already taken the covenant of the Children of Israel and had sent to them messengers. Whenever there came to them a messenger with what their souls did not desire, a party [of messengers] they denied, and another party they killed.","tr":"Laqad akhathna meethaqabanee isra-eela waarsalna ilayhim rusulan kullamajaahum rasoolun bima la tahwaanfusuhum fareeqan kaththaboo wafareeqan yaqtuloon","juz":6,"page":119},{"s":5,"a":71,"key":"5:71","ar":"وَحَسِبُوٓا۟ أَلَّا تَكُونَ فِتْنَةٌ فَعَمُوا۟ وَصَمُّوا۟ ثُمَّ تَابَ ٱللَّهُ عَلَيْهِمْ ثُمَّ عَمُوا۟ وَصَمُّوا۟ كَثِيرٌ مِّنْهُمْ ۚ وَٱللَّهُ بَصِيرٌۢ بِمَا يَعْمَلُونَ","en":"And they thought there would be no [resulting] punishment, so they became blind and deaf. Then Allāh turned to them in forgiveness; then [again] many of them became blind and deaf. And Allāh is Seeing of what they do.","tr":"Wahasiboo alla takoonafitnatun faAAamoo wasammoo thumma taba AllahuAAalayhim thumma AAamoo wasammoo katheerun minhum wallahubaseerun bima yaAAmaloon","juz":6,"page":120},{"s":5,"a":72,"key":"5:72","ar":"لَقَدْ كَفَرَ ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ هُوَ ٱلْمَسِيحُ ٱبْنُ مَرْيَمَ ۖ وَقَالَ ٱلْمَسِيحُ يَـٰبَنِىٓ إِسْرَٰٓءِيلَ ٱعْبُدُوا۟ ٱللَّهَ رَبِّى وَرَبَّكُمْ ۖ إِنَّهُۥ مَن يُشْرِكْ بِٱللَّهِ فَقَدْ حَرَّمَ ٱللَّهُ عَلَيْهِ ٱلْجَنَّةَ وَمَأْوَىٰهُ ٱلنَّارُ ۖ وَمَا لِلظَّـٰلِمِينَ مِنْ أَنصَارٍ","en":"They have certainly disbelieved who say, \"Allāh is the Messiah, the son of Mary\" while the Messiah has said, \"O Children of Israel, worship Allāh, my Lord and your Lord.\" Indeed, he who associates others with Allāh - Allāh has forbidden him Paradise, and his refuge is the Fire. And there are not for the wrongdoers any helpers.","tr":"Laqad kafara allatheena qalooinna Allaha huwa almaseehu ibnu maryama waqalaalmaseehu ya banee isra-eela oAAbudoo Allaharabbee warabbakum innahu man yushrik billahi faqadharrama Allahu AAalayhi aljannata wama/wahuannaru wama liththalimeenamin ansar","juz":6,"page":120},{"s":5,"a":73,"key":"5:73","ar":"لَّقَدْ كَفَرَ ٱلَّذِينَ قَالُوٓا۟ إِنَّ ٱللَّهَ ثَالِثُ ثَلَـٰثَةٍ ۘ وَمَا مِنْ إِلَـٰهٍ إِلَّآ إِلَـٰهٌ وَٰحِدٌ ۚ وَإِن لَّمْ يَنتَهُوا۟ عَمَّا يَقُولُونَ لَيَمَسَّنَّ ٱلَّذِينَ كَفَرُوا۟ مِنْهُمْ عَذَابٌ أَلِيمٌ","en":"They have certainly disbelieved who say, \"Allāh is the third of three.\"1 And there is no god except one God. And if they do not desist from what they are saying, there will surely afflict the disbelievers among them a painful punishment.","tr":"Laqad kafara allatheena qalooinna Allaha thalithu thalathatin wamamin ilahin illa ilahun wahidun wa-inlam yantahoo AAamma yaqooloona layamassanna allatheenakafaroo minhum AAathabun aleem","juz":6,"page":120},{"s":5,"a":74,"key":"5:74","ar":"أَفَلَا يَتُوبُونَ إِلَى ٱللَّهِ وَيَسْتَغْفِرُونَهُۥ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"So will they not repent to Allāh and seek His forgiveness? And Allāh is Forgiving and Merciful.","tr":"Afala yatooboona ila Allahiwayastaghfiroonahu wallahu ghafoorun raheem","juz":6,"page":120},{"s":5,"a":75,"key":"5:75","ar":"مَّا ٱلْمَسِيحُ ٱبْنُ مَرْيَمَ إِلَّا رَسُولٌ قَدْ خَلَتْ مِن قَبْلِهِ ٱلرُّسُلُ وَأُمُّهُۥ صِدِّيقَةٌ ۖ كَانَا يَأْكُلَانِ ٱلطَّعَامَ ۗ ٱنظُرْ كَيْفَ نُبَيِّنُ لَهُمُ ٱلْـَٔايَـٰتِ ثُمَّ ٱنظُرْ أَنَّىٰ يُؤْفَكُونَ","en":"The Messiah, son of Mary, was not but a messenger; [other] messengers have passed on before him. And his mother was a supporter of truth. They both used to eat food.1 Look how We make clear to them the signs; then look how they are deluded.","tr":"Ma almaseehu ibnu maryama illarasoolun qad khalat min qablihi arrusulu waommuhu siddeeqatunkana ya/kulani attaAAamaonthur kayfa nubayyinu lahumu al-ayatithumma onthur anna yu/fakoon","juz":6,"page":120},{"s":5,"a":76,"key":"5:76","ar":"قُلْ أَتَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَمْلِكُ لَكُمْ ضَرًّا وَلَا نَفْعًا ۚ وَٱللَّهُ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"Say, \"Do you worship besides Allāh that which holds for you no [power of] harm or benefit while it is Allāh who is the Hearing, the Knowing?\"","tr":"Qul ataAAbudoona min dooni Allahi mala yamliku lakum darran wala nafAAan wallahuhuwa assameeAAu alAAaleem","juz":6,"page":120},{"s":5,"a":77,"key":"5:77","ar":"قُلْ يَـٰٓأَهْلَ ٱلْكِتَـٰبِ لَا تَغْلُوا۟ فِى دِينِكُمْ غَيْرَ ٱلْحَقِّ وَلَا تَتَّبِعُوٓا۟ أَهْوَآءَ قَوْمٍ قَدْ ضَلُّوا۟ مِن قَبْلُ وَأَضَلُّوا۟ كَثِيرًا وَضَلُّوا۟ عَن سَوَآءِ ٱلسَّبِيلِ","en":"Say, \"O People of the Scripture, do not exceed limits in your religion beyond the truth and do not follow the inclinations of a people who had gone astray before and misled many and have strayed from the soundness of the way.\"","tr":"Qul ya ahla alkitabi lataghloo fee deenikum ghayra alhaqqi wala tattabiAAooahwaa qawmin qad dalloo min qablu waadallookatheeran wadalloo AAan sawa-i assabeel","juz":6,"page":121},{"s":5,"a":78,"key":"5:78","ar":"لُعِنَ ٱلَّذِينَ كَفَرُوا۟ مِنۢ بَنِىٓ إِسْرَٰٓءِيلَ عَلَىٰ لِسَانِ دَاوُۥدَ وَعِيسَى ٱبْنِ مَرْيَمَ ۚ ذَٰلِكَ بِمَا عَصَوا۟ وَّكَانُوا۟ يَعْتَدُونَ","en":"Cursed were those who disbelieved among the Children of Israel by the tongue of David and of Jesus, the son of Mary. That was because they disobeyed and [habitually] transgressed.","tr":"LuAAina allatheena kafaroo min baneeisra-eela AAala lisani dawoodawaAAeesa ibni maryama thalika bima AAasawwakanoo yaAAtadoon","juz":6,"page":121},{"s":5,"a":79,"key":"5:79","ar":"كَانُوا۟ لَا يَتَنَاهَوْنَ عَن مُّنكَرٍ فَعَلُوهُ ۚ لَبِئْسَ مَا كَانُوا۟ يَفْعَلُونَ","en":"They used not to prevent one another from wrongdoing that they did. How wretched was that which they were doing.","tr":"Kanoo la yatanahawnaAAan munkarin faAAaloohu labi/sa ma kanooyafAAaloon","juz":6,"page":121},{"s":5,"a":80,"key":"5:80","ar":"تَرَىٰ كَثِيرًا مِّنْهُمْ يَتَوَلَّوْنَ ٱلَّذِينَ كَفَرُوا۟ ۚ لَبِئْسَ مَا قَدَّمَتْ لَهُمْ أَنفُسُهُمْ أَن سَخِطَ ٱللَّهُ عَلَيْهِمْ وَفِى ٱلْعَذَابِ هُمْ خَـٰلِدُونَ","en":"You see many of them becoming allies of those who disbelieved [i.e., the polytheists]. How wretched is that which they have put forth for themselves in that Allāh has become angry with them, and in the punishment they will abide eternally.","tr":"Tara katheeran minhum yatawallawnaallatheena kafaroo labi/sa ma qaddamat lahumanfusuhum an sakhita Allahu AAalayhim wafee alAAathabihum khalidoon","juz":6,"page":121},{"s":5,"a":81,"key":"5:81","ar":"وَلَوْ كَانُوا۟ يُؤْمِنُونَ بِٱللَّهِ وَٱلنَّبِىِّ وَمَآ أُنزِلَ إِلَيْهِ مَا ٱتَّخَذُوهُمْ أَوْلِيَآءَ وَلَـٰكِنَّ كَثِيرًا مِّنْهُمْ فَـٰسِقُونَ","en":"And if they had believed in Allāh and the Prophet and in what was revealed to him, they would not have taken them as allies; but many of them are defiantly disobedient.","tr":"Walaw kanoo yu/minoona billahiwannabiyyi wama onzila ilayhi ma ittakhathoohumawliyaa walakinna katheeran minhum fasiqoon","juz":6,"page":121},{"s":5,"a":82,"key":"5:82","ar":"۞ لَتَجِدَنَّ أَشَدَّ ٱلنَّاسِ عَدَٰوَةً لِّلَّذِينَ ءَامَنُوا۟ ٱلْيَهُودَ وَٱلَّذِينَ أَشْرَكُوا۟ ۖ وَلَتَجِدَنَّ أَقْرَبَهُم مَّوَدَّةً لِّلَّذِينَ ءَامَنُوا۟ ٱلَّذِينَ قَالُوٓا۟ إِنَّا نَصَـٰرَىٰ ۚ ذَٰلِكَ بِأَنَّ مِنْهُمْ قِسِّيسِينَ وَرُهْبَانًا وَأَنَّهُمْ لَا يَسْتَكْبِرُونَ","en":"You will surely find the most intense of the people in animosity toward the believers [to be] the Jews and those who associate others with Allāh; and you will find the nearest of them in affection to the believers those who say, \"We are Christians.\" That is because among them are priests and monks and because they are not arrogant.","tr":"Latajidanna ashadda annasiAAadawatan lillatheena amanoo alyahooda wallatheenaashrakoo walatajidanna aqrabahum mawaddatan lillatheena amanooallatheena qaloo inna nasara thalikabi-anna minhum qisseeseena waruhbanan waannahum layastakbiroon","juz":7,"page":121},{"s":5,"a":83,"key":"5:83","ar":"وَإِذَا سَمِعُوا۟ مَآ أُنزِلَ إِلَى ٱلرَّسُولِ تَرَىٰٓ أَعْيُنَهُمْ تَفِيضُ مِنَ ٱلدَّمْعِ مِمَّا عَرَفُوا۟ مِنَ ٱلْحَقِّ ۖ يَقُولُونَ رَبَّنَآ ءَامَنَّا فَٱكْتُبْنَا مَعَ ٱلشَّـٰهِدِينَ","en":"And when they hear what has been revealed to the Messenger, you see their eyes overflowing with tears because of what they have recognized of the truth. They say, \"Our Lord, we have believed, so register us among the witnesses.","tr":"Wa-itha samiAAoo ma onzila ilaarrasooli tara aAAyunahum tafeedu mina addamAAimimma AAarafoo mina alhaqqi yaqooloona rabbanaamanna faktubna maAAa ashshahideen","juz":7,"page":122},{"s":5,"a":84,"key":"5:84","ar":"وَمَا لَنَا لَا نُؤْمِنُ بِٱللَّهِ وَمَا جَآءَنَا مِنَ ٱلْحَقِّ وَنَطْمَعُ أَن يُدْخِلَنَا رَبُّنَا مَعَ ٱلْقَوْمِ ٱلصَّـٰلِحِينَ","en":"And why should we not believe in Allāh and what has come to us of the truth? And we aspire that our Lord will admit us [to Paradise] with the righteous people.\"","tr":"Wama lana la nu/minu billahiwama jaana mina alhaqqi wanatmaAAuan yudkhilana rabbuna maAAa alqawmi assaliheen","juz":7,"page":122},{"s":5,"a":85,"key":"5:85","ar":"فَأَثَـٰبَهُمُ ٱللَّهُ بِمَا قَالُوا۟ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا ۚ وَذَٰلِكَ جَزَآءُ ٱلْمُحْسِنِينَ","en":"So Allāh rewarded them for what they said1 with gardens [in Paradise] beneath which rivers flow, wherein they abide eternally. And that is the reward of doers of good.","tr":"Faathabahumu Allahu bimaqaloo jannatin tajree min tahtihaal-anharu khalideena feeha wathalikajazao almuhsineen","juz":7,"page":122},{"s":5,"a":86,"key":"5:86","ar":"وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَـٰتِنَآ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْجَحِيمِ","en":"But those who disbelieved and denied Our signs - they are the companions of Hellfire.","tr":"Wallatheena kafaroo wakaththaboobi-ayatina ola-ika as-habualjaheem","juz":7,"page":122},{"s":5,"a":87,"key":"5:87","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تُحَرِّمُوا۟ طَيِّبَـٰتِ مَآ أَحَلَّ ٱللَّهُ لَكُمْ وَلَا تَعْتَدُوٓا۟ ۚ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْمُعْتَدِينَ","en":"O you who have believed, do not prohibit the good things which Allāh has made lawful to you and do not transgress. Indeed, Allāh does not like transgressors.","tr":"Ya ayyuha allatheena amanoola tuharrimoo tayyibati ma ahallaAllahu lakum wala taAAtadoo inna Allaha layuhibbu almuAAtadeen","juz":7,"page":122},{"s":5,"a":88,"key":"5:88","ar":"وَكُلُوا۟ مِمَّا رَزَقَكُمُ ٱللَّهُ حَلَـٰلًا طَيِّبًا ۚ وَٱتَّقُوا۟ ٱللَّهَ ٱلَّذِىٓ أَنتُم بِهِۦ مُؤْمِنُونَ","en":"And eat of what Allāh has provided for you [which is] lawful and good. And fear Allāh, in whom you are believers.","tr":"Wakuloo mimma razaqakumu Allahuhalalan tayyiban wattaqoo Allahaallathee antum bihi mu/minoon","juz":7,"page":122},{"s":5,"a":89,"key":"5:89","ar":"لَا يُؤَاخِذُكُمُ ٱللَّهُ بِٱللَّغْوِ فِىٓ أَيْمَـٰنِكُمْ وَلَـٰكِن يُؤَاخِذُكُم بِمَا عَقَّدتُّمُ ٱلْأَيْمَـٰنَ ۖ فَكَفَّـٰرَتُهُۥٓ إِطْعَامُ عَشَرَةِ مَسَـٰكِينَ مِنْ أَوْسَطِ مَا تُطْعِمُونَ أَهْلِيكُمْ أَوْ كِسْوَتُهُمْ أَوْ تَحْرِيرُ رَقَبَةٍ ۖ فَمَن لَّمْ يَجِدْ فَصِيَامُ ثَلَـٰثَةِ أَيَّامٍ ۚ ذَٰلِكَ كَفَّـٰرَةُ أَيْمَـٰنِكُمْ إِذَا حَلَفْتُمْ ۚ وَٱحْفَظُوٓا۟ أَيْمَـٰنَكُمْ ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَـٰتِهِۦ لَعَلَّكُمْ تَشْكُرُونَ","en":"Allāh will not impose blame upon you for what is meaningless1 in your oaths, but He will impose blame upon you for [breaking] what you intended of oaths. So its expiation2 is the feeding of ten needy people from the average of that which you feed your [own] families or clothing them or the freeing of a slave. But whoever cannot find [or afford it] - then a fast of three days [is required]. That is the expiation for oaths when you have sworn. But guard your oaths.3 Thus does Allāh make clear to you His verses [i.e., revealed law] that you may be grateful.","tr":"La yu-akhithukumu Allahubillaghwi fee aymanikum walakin yu-akhithukumbima AAaqqadtumu al-aymana fakaffaratuhu itAAamuAAasharati masakeena min awsati ma tutAAimoonaahleekum aw kiswatuhum aw tahreeru raqabatin faman lamyajid fasiyamu thalathati ayyamin thalikakaffaratu aymanikum itha halaftum wahfathooaymanakum kathalika yubayyinu Allahu lakum ayatihilaAAallakum tashkuroon","juz":7,"page":122},{"s":5,"a":90,"key":"5:90","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّمَا ٱلْخَمْرُ وَٱلْمَيْسِرُ وَٱلْأَنصَابُ وَٱلْأَزْلَـٰمُ رِجْسٌ مِّنْ عَمَلِ ٱلشَّيْطَـٰنِ فَٱجْتَنِبُوهُ لَعَلَّكُمْ تُفْلِحُونَ","en":"O you who have believed, indeed, intoxicants, gambling, [sacrificing on] stone alters [to other than Allāh], and divining arrows are but defilement from the work of Satan, so avoid1 it that you may be successful.","tr":"Ya ayyuha allatheena amanooinnama alkhamru walmaysiru wal-ansabuwal-azlamu rijsun min AAamali ashshaytanifajtaniboohu laAAallakum tuflihoon","juz":7,"page":123},{"s":5,"a":91,"key":"5:91","ar":"إِنَّمَا يُرِيدُ ٱلشَّيْطَـٰنُ أَن يُوقِعَ بَيْنَكُمُ ٱلْعَدَٰوَةَ وَٱلْبَغْضَآءَ فِى ٱلْخَمْرِ وَٱلْمَيْسِرِ وَيَصُدَّكُمْ عَن ذِكْرِ ٱللَّهِ وَعَنِ ٱلصَّلَوٰةِ ۖ فَهَلْ أَنتُم مُّنتَهُونَ","en":"Satan only wants to cause between you animosity and hatred through intoxicants and gambling and to avert you from the remembrance of Allāh and from prayer. So will you not desist?","tr":"Innama yureedu ashshaytanuan yooqiAAa baynakumu alAAadawata walbaghdaafee alkhamri walmaysiri wayasuddakum AAan thikriAllahi waAAani assalati fahal antummuntahoon","juz":7,"page":123},{"s":5,"a":92,"key":"5:92","ar":"وَأَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ وَٱحْذَرُوا۟ ۚ فَإِن تَوَلَّيْتُمْ فَٱعْلَمُوٓا۟ أَنَّمَا عَلَىٰ رَسُولِنَا ٱلْبَلَـٰغُ ٱلْمُبِينُ","en":"And obey Allāh and obey the Messenger and beware. And if you turn away - then know that upon Our Messenger is only [the responsibility for] clear notification.","tr":"WaateeAAoo Allaha waateeAAooarrasoola wahtharoo fa-in tawallaytum faAAlamooannama AAala rasoolina albalaghualmubeen","juz":7,"page":123},{"s":5,"a":93,"key":"5:93","ar":"لَيْسَ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جُنَاحٌ فِيمَا طَعِمُوٓا۟ إِذَا مَا ٱتَّقَوا۟ وَّءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ ثُمَّ ٱتَّقَوا۟ وَّءَامَنُوا۟ ثُمَّ ٱتَّقَوا۟ وَّأَحْسَنُوا۟ ۗ وَٱللَّهُ يُحِبُّ ٱلْمُحْسِنِينَ","en":"There is not upon those who believe and do righteousness [any] blame concerning what they have eaten [in the past] if they [now] fear Allāh and believe and do righteous deeds, and then fear Allāh and believe, and then fear Allāh and do good; and Allāh loves the doers of good.","tr":"Laysa AAala allatheena amanoowaAAamiloo assalihati junahun feemataAAimoo itha ma ittaqaw waamanoowaAAamiloo assalihati thumma ittaqaw waamanoothumma ittaqaw waahsanoo wallahu yuhibbualmuhsineen","juz":7,"page":123},{"s":5,"a":94,"key":"5:94","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَيَبْلُوَنَّكُمُ ٱللَّهُ بِشَىْءٍ مِّنَ ٱلصَّيْدِ تَنَالُهُۥٓ أَيْدِيكُمْ وَرِمَاحُكُمْ لِيَعْلَمَ ٱللَّهُ مَن يَخَافُهُۥ بِٱلْغَيْبِ ۚ فَمَنِ ٱعْتَدَىٰ بَعْدَ ذَٰلِكَ فَلَهُۥ عَذَابٌ أَلِيمٌ","en":"O you who have believed, Allāh will surely test you through something of the game that your hands and spears [can] reach, that Allāh may make evident those who fear Him unseen. And whoever transgresses after that - for him is a painful punishment.","tr":"Ya ayyuha allatheena amanoolayabluwannakumu Allahu bishay-in mina assayditanaluhu aydeekum warimahukum liyaAAlama Allahuman yakhafuhu bilghaybi famani iAAtadabaAAda thalika falahu AAathabun aleem","juz":7,"page":123},{"s":5,"a":95,"key":"5:95","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَقْتُلُوا۟ ٱلصَّيْدَ وَأَنتُمْ حُرُمٌ ۚ وَمَن قَتَلَهُۥ مِنكُم مُّتَعَمِّدًا فَجَزَآءٌ مِّثْلُ مَا قَتَلَ مِنَ ٱلنَّعَمِ يَحْكُمُ بِهِۦ ذَوَا عَدْلٍ مِّنكُمْ هَدْيًۢا بَـٰلِغَ ٱلْكَعْبَةِ أَوْ كَفَّـٰرَةٌ طَعَامُ مَسَـٰكِينَ أَوْ عَدْلُ ذَٰلِكَ صِيَامًا لِّيَذُوقَ وَبَالَ أَمْرِهِۦ ۗ عَفَا ٱللَّهُ عَمَّا سَلَفَ ۚ وَمَنْ عَادَ فَيَنتَقِمُ ٱللَّهُ مِنْهُ ۗ وَٱللَّهُ عَزِيزٌ ذُو ٱنتِقَامٍ","en":"O you who have believed, do not kill game while you are in the state of iḥrām.1 And whoever of you kills it intentionally - the penalty is an equivalent from sacrificial animals to what he killed, as judged by two just men among you as an offering [to Allāh] delivered to the Kaʿbah, or an expiation: the feeding of needy people or the equivalent of that in fasting, that he may taste the consequence of his matter [i.e., deed]. Allāh has pardoned what is past; but whoever returns [to violation], then Allāh will take retribution from him. And Allāh is Exalted in Might and Owner of Retribution.2","tr":"Ya ayyuha allatheena amanoola taqtuloo assayda waantum hurumunwaman qatalahu minkum mutaAAammidan fajazaon mithlu maqatala mina annaAAami yahkumu bihi thawaAAadlin minkum hadyan baligha alkaAAbati aw kaffaratuntaAAamu masakeena aw AAadlu thalika siyamanliyathooqa wabala amrihi AAafa AllahuAAamma salafa waman AAada fayantaqimu Allahuminhu wallahu AAazeezun thoo intiqam","juz":7,"page":123},{"s":5,"a":96,"key":"5:96","ar":"أُحِلَّ لَكُمْ صَيْدُ ٱلْبَحْرِ وَطَعَامُهُۥ مَتَـٰعًا لَّكُمْ وَلِلسَّيَّارَةِ ۖ وَحُرِّمَ عَلَيْكُمْ صَيْدُ ٱلْبَرِّ مَا دُمْتُمْ حُرُمًا ۗ وَٱتَّقُوا۟ ٱللَّهَ ٱلَّذِىٓ إِلَيْهِ تُحْشَرُونَ","en":"Lawful to you is game from the sea and its food as provision for you and the travelers,1 but forbidden to you is game from the land as long as you are in the state of iḥrām. And fear Allāh to whom you will be gathered.","tr":"Ohilla lakum saydu albahriwataAAamuhu mataAAan lakum walissayyaratiwahurrima AAalaykum saydu albarri ma dumtum hurumanwattaqoo Allaha allathee ilayhi tuhsharoon","juz":7,"page":124},{"s":5,"a":97,"key":"5:97","ar":"۞ جَعَلَ ٱللَّهُ ٱلْكَعْبَةَ ٱلْبَيْتَ ٱلْحَرَامَ قِيَـٰمًا لِّلنَّاسِ وَٱلشَّهْرَ ٱلْحَرَامَ وَٱلْهَدْىَ وَٱلْقَلَـٰٓئِدَ ۚ ذَٰلِكَ لِتَعْلَمُوٓا۟ أَنَّ ٱللَّهَ يَعْلَمُ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ وَأَنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"Allāh has made the Kaʿbah, the Sacred House, standing1 for the people and [has sanctified] the sacred months and the sacrificial animals and the garlands [by which they are identified]. That is so you may know that Allāh knows what is in the heavens and what is in the earth and that Allāh is Knowing of all things.","tr":"JaAAala Allahu alkaAAbata albayta alharamaqiyaman linnasi washshahra alharamawalhadya walqala-ida thalikalitaAAlamoo anna Allaha yaAAlamu ma fee assamawatiwama fee al-ardi waanna Allaha bikullishay-in AAaleem","juz":7,"page":124},{"s":5,"a":98,"key":"5:98","ar":"ٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ وَأَنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"Know that Allāh is severe in penalty and that Allāh is Forgiving and Merciful.","tr":"IAAlamoo anna Allaha shadeedu alAAiqabiwaanna Allaha ghafoorun raheem","juz":7,"page":124},{"s":5,"a":99,"key":"5:99","ar":"مَّا عَلَى ٱلرَّسُولِ إِلَّا ٱلْبَلَـٰغُ ۗ وَٱللَّهُ يَعْلَمُ مَا تُبْدُونَ وَمَا تَكْتُمُونَ","en":"Not upon the Messenger is [responsibility] except [for] notification. And Allāh knows whatever you reveal and whatever you conceal.","tr":"Ma AAala arrasooli illaalbalaghu wallahu yaAAlamu matubdoona wama taktumoon","juz":7,"page":124},{"s":5,"a":100,"key":"5:100","ar":"قُل لَّا يَسْتَوِى ٱلْخَبِيثُ وَٱلطَّيِّبُ وَلَوْ أَعْجَبَكَ كَثْرَةُ ٱلْخَبِيثِ ۚ فَٱتَّقُوا۟ ٱللَّهَ يَـٰٓأُو۟لِى ٱلْأَلْبَـٰبِ لَعَلَّكُمْ تُفْلِحُونَ","en":"Say, \"Not equal are the evil and the good, although the abundance of evil might impress you.\" So fear Allāh, O you of understanding, that you may be successful.","tr":"Qul la yastawee alkhabeethu wattayyibuwalaw aAAjabaka kathratu alkhabeethi fattaqoo Allahaya olee al-albabi laAAallakum tuflihoon","juz":7,"page":124},{"s":5,"a":101,"key":"5:101","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَسْـَٔلُوا۟ عَنْ أَشْيَآءَ إِن تُبْدَ لَكُمْ تَسُؤْكُمْ وَإِن تَسْـَٔلُوا۟ عَنْهَا حِينَ يُنَزَّلُ ٱلْقُرْءَانُ تُبْدَ لَكُمْ عَفَا ٱللَّهُ عَنْهَا ۗ وَٱللَّهُ غَفُورٌ حَلِيمٌ","en":"O you who have believed, do not ask about things which, if they are shown to you, will distress you. But if you ask about them while the Qur’ān is being revealed, they will be shown to you. Allāh has pardoned it [i.e., that which is past]; and Allāh is Forgiving and Forbearing.","tr":"Ya ayyuha allatheena amanoola tas-aloo AAan ashyaa in tubda lakum tasu/kumwa-in tas-aloo AAanha heena yunazzalu alqur-anutubda lakum AAafa Allahu AAanha wallahughafoorun haleem","juz":7,"page":124},{"s":5,"a":102,"key":"5:102","ar":"قَدْ سَأَلَهَا قَوْمٌ مِّن قَبْلِكُمْ ثُمَّ أَصْبَحُوا۟ بِهَا كَـٰفِرِينَ","en":"A people asked such [questions] before you; then they became thereby disbelievers.1","tr":"Qad saalaha qawmun min qablikumthumma asbahoo biha kafireen","juz":7,"page":124},{"s":5,"a":103,"key":"5:103","ar":"مَا جَعَلَ ٱللَّهُ مِنۢ بَحِيرَةٍ وَلَا سَآئِبَةٍ وَلَا وَصِيلَةٍ وَلَا حَامٍ ۙ وَلَـٰكِنَّ ٱلَّذِينَ كَفَرُوا۟ يَفْتَرُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ ۖ وَأَكْثَرُهُمْ لَا يَعْقِلُونَ","en":"Allāh has not appointed [such innovations as] baḥīrah or sā’ibah or waṣīlah or ḥām.1 But those who disbelieve invent falsehood about Allāh, and most of them do not reason.","tr":"Ma jaAAala Allahu min baheeratinwala sa-ibatin wala waseelatin walahamin walakinna allatheena kafarooyaftaroona AAala Allahi alkathibawaaktharuhum la yaAAqiloon","juz":7,"page":124},{"s":5,"a":104,"key":"5:104","ar":"وَإِذَا قِيلَ لَهُمْ تَعَالَوْا۟ إِلَىٰ مَآ أَنزَلَ ٱللَّهُ وَإِلَى ٱلرَّسُولِ قَالُوا۟ حَسْبُنَا مَا وَجَدْنَا عَلَيْهِ ءَابَآءَنَآ ۚ أَوَلَوْ كَانَ ءَابَآؤُهُمْ لَا يَعْلَمُونَ شَيْـًٔا وَلَا يَهْتَدُونَ","en":"And when it is said to them, \"Come to what Allāh has revealed and to the Messenger,\" they say, \"Sufficient for us is that upon which we found our fathers.\" Even though their fathers knew nothing, nor were they guided?","tr":"Wa-itha qeela lahum taAAalawila ma anzala Allahu wa-ila arrasooliqaloo hasbuna ma wajadnaAAalayhi abaana awa law kana abaohumla yaAAlamoona shay-an wala yahtadoon","juz":7,"page":125},{"s":5,"a":105,"key":"5:105","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ عَلَيْكُمْ أَنفُسَكُمْ ۖ لَا يَضُرُّكُم مَّن ضَلَّ إِذَا ٱهْتَدَيْتُمْ ۚ إِلَى ٱللَّهِ مَرْجِعُكُمْ جَمِيعًا فَيُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ","en":"O you who have believed, upon you is [responsibility for] yourselves. Those who have gone astray will not harm you when you have been guided. To Allāh is your return all together; then He will inform you of what you used to do.","tr":"Ya ayyuha allatheena amanooAAalaykum anfusakum la yadurrukum man dallaitha ihtadaytum ila Allahi marjiAAukumjameeAAan fayunabbi-okum bima kuntum taAAmaloon","juz":7,"page":125},{"s":5,"a":106,"key":"5:106","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ شَهَـٰدَةُ بَيْنِكُمْ إِذَا حَضَرَ أَحَدَكُمُ ٱلْمَوْتُ حِينَ ٱلْوَصِيَّةِ ٱثْنَانِ ذَوَا عَدْلٍ مِّنكُمْ أَوْ ءَاخَرَانِ مِنْ غَيْرِكُمْ إِنْ أَنتُمْ ضَرَبْتُمْ فِى ٱلْأَرْضِ فَأَصَـٰبَتْكُم مُّصِيبَةُ ٱلْمَوْتِ ۚ تَحْبِسُونَهُمَا مِنۢ بَعْدِ ٱلصَّلَوٰةِ فَيُقْسِمَانِ بِٱللَّهِ إِنِ ٱرْتَبْتُمْ لَا نَشْتَرِى بِهِۦ ثَمَنًا وَلَوْ كَانَ ذَا قُرْبَىٰ ۙ وَلَا نَكْتُمُ شَهَـٰدَةَ ٱللَّهِ إِنَّآ إِذًا لَّمِنَ ٱلْـَٔاثِمِينَ","en":"O you who have believed, testimony [should be taken] among you when death approaches one of you at the time of bequest - [that of] two just men from among you or two others from outside if you are traveling through the land and the disaster of death should strike you. Detain them after the prayer and let them both swear by Allāh if you doubt [their testimony, saying], \"We will not exchange it [i.e., our oath] for a price [i.e., worldly gain], even if he should be a near relative, and we will not withhold the testimony of [i.e., ordained by] Allāh. Indeed, we would then be of the sinful.\"","tr":"Ya ayyuha allatheena amanooshahadatu baynikum itha hadara ahadakumualmawtu heena alwasiyyati ithnani thawaAAadlin minkum aw akharani min ghayrikum in antum darabtumfee al-ardi faasabatkum museebatu almawti tahbisoonahumamin baAAdi assalati fayuqsimani billahiini irtabtum la nashtaree bihi thamanan walaw kana thaqurba wala naktumu shahadata Allahiinna ithan lamina al-athimeen","juz":7,"page":125},{"s":5,"a":107,"key":"5:107","ar":"فَإِنْ عُثِرَ عَلَىٰٓ أَنَّهُمَا ٱسْتَحَقَّآ إِثْمًا فَـَٔاخَرَانِ يَقُومَانِ مَقَامَهُمَا مِنَ ٱلَّذِينَ ٱسْتَحَقَّ عَلَيْهِمُ ٱلْأَوْلَيَـٰنِ فَيُقْسِمَانِ بِٱللَّهِ لَشَهَـٰدَتُنَآ أَحَقُّ مِن شَهَـٰدَتِهِمَا وَمَا ٱعْتَدَيْنَآ إِنَّآ إِذًا لَّمِنَ ٱلظَّـٰلِمِينَ","en":"But if it is found that those two were guilty of sin [i.e., perjury], let two others stand in their place [who are] foremost [in claim] from those who have a lawful right. And let them swear by Allāh, \"Our testimony is truer than their testimony, and we have not transgressed. Indeed, we would then be of the wrongdoers.\"","tr":"Fa-in AAuthira AAala annahumaistahaqqa ithman faakharani yaqoomanimaqamahuma mina allatheena istahaqqaAAalayhimu al-awlayani fayuqsimani billahilashahadatuna ahaqqu min shahadatihimawama iAAtadayna inna ithan lamina aththalimeen","juz":7,"page":125},{"s":5,"a":108,"key":"5:108","ar":"ذَٰلِكَ أَدْنَىٰٓ أَن يَأْتُوا۟ بِٱلشَّهَـٰدَةِ عَلَىٰ وَجْهِهَآ أَوْ يَخَافُوٓا۟ أَن تُرَدَّ أَيْمَـٰنٌۢ بَعْدَ أَيْمَـٰنِهِمْ ۗ وَٱتَّقُوا۟ ٱللَّهَ وَٱسْمَعُوا۟ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلْفَـٰسِقِينَ","en":"That is more likely that they will give testimony according to its [true] objective, or [at least] they would fear that [other] oaths might be taken after their oaths. And fear Allāh and listen [i.e., obey Him]; and Allāh does not guide the defiantly disobedient people.","tr":"Thalika adna an ya/too bishshahadatiAAala wajhiha aw yakhafoo an turadda aymanunbaAAda aymanihim wattaqoo Allaha wasmaAAoowallahu la yahdee alqawma alfasiqeen","juz":7,"page":125},{"s":5,"a":109,"key":"5:109","ar":"۞ يَوْمَ يَجْمَعُ ٱللَّهُ ٱلرُّسُلَ فَيَقُولُ مَاذَآ أُجِبْتُمْ ۖ قَالُوا۟ لَا عِلْمَ لَنَآ ۖ إِنَّكَ أَنتَ عَلَّـٰمُ ٱلْغُيُوبِ","en":"[Be warned of] the Day when Allāh will assemble the messengers and say, \"What was the response you received?\" They will say, \"We have no knowledge. Indeed, it is You who is Knower of the unseen\" -","tr":"Yawma yajmaAAu Allahu arrusulafayaqoolu matha ojibtum qaloo la AAilma lanainnaka anta AAallamu alghuyoob","juz":7,"page":126},{"s":5,"a":110,"key":"5:110","ar":"إِذْ قَالَ ٱللَّهُ يَـٰعِيسَى ٱبْنَ مَرْيَمَ ٱذْكُرْ نِعْمَتِى عَلَيْكَ وَعَلَىٰ وَٰلِدَتِكَ إِذْ أَيَّدتُّكَ بِرُوحِ ٱلْقُدُسِ تُكَلِّمُ ٱلنَّاسَ فِى ٱلْمَهْدِ وَكَهْلًا ۖ وَإِذْ عَلَّمْتُكَ ٱلْكِتَـٰبَ وَٱلْحِكْمَةَ وَٱلتَّوْرَىٰةَ وَٱلْإِنجِيلَ ۖ وَإِذْ تَخْلُقُ مِنَ ٱلطِّينِ كَهَيْـَٔةِ ٱلطَّيْرِ بِإِذْنِى فَتَنفُخُ فِيهَا فَتَكُونُ طَيْرًۢا بِإِذْنِى ۖ وَتُبْرِئُ ٱلْأَكْمَهَ وَٱلْأَبْرَصَ بِإِذْنِى ۖ وَإِذْ تُخْرِجُ ٱلْمَوْتَىٰ بِإِذْنِى ۖ وَإِذْ كَفَفْتُ بَنِىٓ إِسْرَٰٓءِيلَ عَنكَ إِذْ جِئْتَهُم بِٱلْبَيِّنَـٰتِ فَقَالَ ٱلَّذِينَ كَفَرُوا۟ مِنْهُمْ إِنْ هَـٰذَآ إِلَّا سِحْرٌ مُّبِينٌ","en":"[The Day] when Allāh will say, \"O Jesus, Son of Mary, remember My favor upon you and upon your mother when I supported you with the Pure Spirit [i.e., the angel Gabriel] and you spoke to the people in the cradle and in maturity; and [remember] when I taught you writing and wisdom and the Torah and the Gospel; and when you designed from clay [what was] like the form of a bird with My permission, then you breathed into it, and it became a bird with My permission; and you healed the blind [from birth] and the leper with My permission; and when you brought forth the dead with My permission; and when I restrained the Children of Israel from [killing] you when you came to them with clear proofs and those who disbelieved among them said, \"This is not but obvious magic.\"","tr":"Ith qala Allahu yaAAeesa ibna maryama othkur niAAmatee AAalaykawaAAala walidatika ith ayyadtuka biroohialqudusi tukallimu annasa fee almahdi wakahlanwa-ith AAallamtuka alkitaba walhikmatawattawrata wal-injeela wa-ithtakhluqu mina atteeni kahay-ati attayribi-ithnee fatanfukhu feeha fatakoonu tayranbi-ithnee watubri-o al-akmaha wal-abrasabi-ithnee wa-ith tukhriju almawta bi-ithneewa-ith kafaftu banee isra-eela AAanka ithji/tahum bilbayyinati faqala allatheenakafaroo minhum in hatha illa sihrun mubeen","juz":7,"page":126},{"s":5,"a":111,"key":"5:111","ar":"وَإِذْ أَوْحَيْتُ إِلَى ٱلْحَوَارِيِّـۧنَ أَنْ ءَامِنُوا۟ بِى وَبِرَسُولِى قَالُوٓا۟ ءَامَنَّا وَٱشْهَدْ بِأَنَّنَا مُسْلِمُونَ","en":"And [remember] when I inspired to the disciples, \"Believe in Me and in My messenger [i.e., Jesus].\" They said, \"We have believed, so bear witness that indeed we are Muslims [in submission to Allāh].\"","tr":"Wa-ith awhaytu ila alhawariyyeenaan aminoo bee wabirasoolee qaloo amannawashhad bi-annana muslimoon","juz":7,"page":126},{"s":5,"a":112,"key":"5:112","ar":"إِذْ قَالَ ٱلْحَوَارِيُّونَ يَـٰعِيسَى ٱبْنَ مَرْيَمَ هَلْ يَسْتَطِيعُ رَبُّكَ أَن يُنَزِّلَ عَلَيْنَا مَآئِدَةً مِّنَ ٱلسَّمَآءِ ۖ قَالَ ٱتَّقُوا۟ ٱللَّهَ إِن كُنتُم مُّؤْمِنِينَ","en":"[And remember] when the disciples said, \"O Jesus, Son of Mary, can your Lord1 send down to us a table [spread with food] from the heaven?\" [Jesus] said, \"Fear Allāh, if you should be believers.\"","tr":"Ith qala alhawariyyoonaya AAeesa ibna maryama hal yastateeAAurabbuka an yunazzila AAalayna ma-idatan mina assama-iqala ittaqoo Allaha in kuntum mu/mineen","juz":7,"page":126},{"s":5,"a":113,"key":"5:113","ar":"قَالُوا۟ نُرِيدُ أَن نَّأْكُلَ مِنْهَا وَتَطْمَئِنَّ قُلُوبُنَا وَنَعْلَمَ أَن قَدْ صَدَقْتَنَا وَنَكُونَ عَلَيْهَا مِنَ ٱلشَّـٰهِدِينَ","en":"They said, \"We wish to eat from it and let our hearts be reassured and know that you have been truthful to us and be among its witnesses.\"","tr":"Qaloo nureedu an na/kula minhawatatma-inna quloobuna wanaAAlama an qad sadaqtanawanakoona AAalayha mina ashshahideen","juz":7,"page":126},{"s":5,"a":114,"key":"5:114","ar":"قَالَ عِيسَى ٱبْنُ مَرْيَمَ ٱللَّهُمَّ رَبَّنَآ أَنزِلْ عَلَيْنَا مَآئِدَةً مِّنَ ٱلسَّمَآءِ تَكُونُ لَنَا عِيدًا لِّأَوَّلِنَا وَءَاخِرِنَا وَءَايَةً مِّنكَ ۖ وَٱرْزُقْنَا وَأَنتَ خَيْرُ ٱلرَّٰزِقِينَ","en":"Said Jesus, the son of Mary, \"O Allāh, our Lord, send down to us a table [spread with food] from the heaven to be for us a festival for the first of us and the last of us and a sign from You. And provide for us, and You are the best of providers.\"","tr":"Qala AAeesa ibnu maryama allahummarabbana anzil AAalayna ma-idatan mina assama-itakoonu lana AAeedan li-awwalina waakhirinawaayatan minka warzuqna waanta khayru arraziqeen","juz":7,"page":127},{"s":5,"a":115,"key":"5:115","ar":"قَالَ ٱللَّهُ إِنِّى مُنَزِّلُهَا عَلَيْكُمْ ۖ فَمَن يَكْفُرْ بَعْدُ مِنكُمْ فَإِنِّىٓ أُعَذِّبُهُۥ عَذَابًا لَّآ أُعَذِّبُهُۥٓ أَحَدًا مِّنَ ٱلْعَـٰلَمِينَ","en":"Allāh said, \"Indeed, I will send it down to you, but whoever disbelieves afterwards from among you - then indeed will I punish him with a punishment by which I have not punished anyone among the worlds.\"","tr":"Qala Allahu innee munazziluhaAAalaykum faman yakfur baAAdu minkum fa-innee oAAaththibuhuAAathaban la oAAaththibuhu ahadanmina alAAalameen","juz":7,"page":127},{"s":5,"a":116,"key":"5:116","ar":"وَإِذْ قَالَ ٱللَّهُ يَـٰعِيسَى ٱبْنَ مَرْيَمَ ءَأَنتَ قُلْتَ لِلنَّاسِ ٱتَّخِذُونِى وَأُمِّىَ إِلَـٰهَيْنِ مِن دُونِ ٱللَّهِ ۖ قَالَ سُبْحَـٰنَكَ مَا يَكُونُ لِىٓ أَنْ أَقُولَ مَا لَيْسَ لِى بِحَقٍّ ۚ إِن كُنتُ قُلْتُهُۥ فَقَدْ عَلِمْتَهُۥ ۚ تَعْلَمُ مَا فِى نَفْسِى وَلَآ أَعْلَمُ مَا فِى نَفْسِكَ ۚ إِنَّكَ أَنتَ عَلَّـٰمُ ٱلْغُيُوبِ","en":"And [beware the Day] when Allāh will say, \"O Jesus, Son of Mary, did you say to the people, 'Take me and my mother as deities besides Allāh?'\" He will say, \"Exalted are You! It was not for me to say that to which I have no right. If I had said it, You would have known it. You know what is within myself, and I do not know what is within Yourself. Indeed, it is You who is Knower of the unseen.","tr":"Wa-ith qala Allahu yaAAeesa ibna maryama aanta qulta linnasiittakhithoonee waommiya ilahayni min dooni Allahiqala subhanaka ma yakoonu lee an aqoola malaysa lee bihaqqin in kuntu qultuhu faqad AAalimtahutaAAlamu ma fee nafsee wala aAAlamu ma feenafsika innaka anta AAallamu alghuyoob","juz":7,"page":127},{"s":5,"a":117,"key":"5:117","ar":"مَا قُلْتُ لَهُمْ إِلَّا مَآ أَمَرْتَنِى بِهِۦٓ أَنِ ٱعْبُدُوا۟ ٱللَّهَ رَبِّى وَرَبَّكُمْ ۚ وَكُنتُ عَلَيْهِمْ شَهِيدًا مَّا دُمْتُ فِيهِمْ ۖ فَلَمَّا تَوَفَّيْتَنِى كُنتَ أَنتَ ٱلرَّقِيبَ عَلَيْهِمْ ۚ وَأَنتَ عَلَىٰ كُلِّ شَىْءٍ شَهِيدٌ","en":"I said not to them except what You commanded me - to worship Allāh, my Lord and your Lord. And I was a witness over them as long as I was among them; but when You took me up, You were the Observer over them, and You are, over all things, Witness.","tr":"Ma qultu lahum illa maamartanee bihi ani oAAbudoo Allaha rabbee warabbakumwakuntu AAalayhim shaheedan ma dumtu feehim falammatawaffaytanee kunta anta arraqeeba AAalayhim waanta AAalakulli shay-in shaheed","juz":7,"page":127},{"s":5,"a":118,"key":"5:118","ar":"إِن تُعَذِّبْهُمْ فَإِنَّهُمْ عِبَادُكَ ۖ وَإِن تَغْفِرْ لَهُمْ فَإِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"If You should punish them - indeed they are Your servants; but if You forgive them - indeed it is You who is the Exalted in Might, the Wise.\"","tr":"In tuAAaththibhum fa-innahum AAibadukawa-in taghfir lahum fa-innaka anta alAAazeezu alhakeem","juz":7,"page":127},{"s":5,"a":119,"key":"5:119","ar":"قَالَ ٱللَّهُ هَـٰذَا يَوْمُ يَنفَعُ ٱلصَّـٰدِقِينَ صِدْقُهُمْ ۚ لَهُمْ جَنَّـٰتٌ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَدًا ۚ رَّضِىَ ٱللَّهُ عَنْهُمْ وَرَضُوا۟ عَنْهُ ۚ ذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"Allāh will say, \"This is the Day when the truthful will benefit from their truthfulness.\" For them are gardens [in Paradise] beneath which rivers flow, wherein they will abide forever, Allāh being pleased with them, and they with Him. That is the great attainment.","tr":"Qala Allahu hathayawmu yanfaAAu assadiqeena sidquhum lahumjannatun tajree min tahtiha al-anharukhalideena feeha abadan radiya AllahuAAanhum waradoo AAanhu thalika alfawzu alAAatheem","juz":7,"page":127},{"s":5,"a":120,"key":"5:120","ar":"لِلَّهِ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا فِيهِنَّ ۚ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌۢ","en":"To Allāh belongs the dominion of the heavens and the earth and whatever is within them. And He is over all things competent.","tr":"Lillahi mulku assamawatiwal-ardi wama feehinna wahuwa AAalakulli shay-in qadeer","juz":7,"page":127},{"s":6,"a":1,"key":"6:1","ar":" ٱلْحَمْدُ لِلَّهِ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَجَعَلَ ٱلظُّلُمَـٰتِ وَٱلنُّورَ ۖ ثُمَّ ٱلَّذِينَ كَفَرُوا۟ بِرَبِّهِمْ يَعْدِلُونَ","en":"[All] praise is [due] to Allāh, who created the heavens and the earth and made the darkness and the light. Then those who disbelieve equate [others] with their Lord.","tr":"Alhamdu lillahi allatheekhalaqa assamawati wal-ardawajaAAala aththulumati wannoorathumma allatheena kafaroo birabbihim yaAAdiloon","juz":7,"page":128},{"s":6,"a":2,"key":"6:2","ar":"هُوَ ٱلَّذِى خَلَقَكُم مِّن طِينٍ ثُمَّ قَضَىٰٓ أَجَلًا ۖ وَأَجَلٌ مُّسَمًّى عِندَهُۥ ۖ ثُمَّ أَنتُمْ تَمْتَرُونَ","en":"It is He who created you from clay and then decreed a term1 and a specified time [known] to Him;2 then [still] you are in dispute.","tr":"Huwa allathee khalaqakum min teeninthumma qada ajalan waajalun musamman AAindahu thumma antumtamtaroon","juz":7,"page":128},{"s":6,"a":3,"key":"6:3","ar":"وَهُوَ ٱللَّهُ فِى ٱلسَّمَـٰوَٰتِ وَفِى ٱلْأَرْضِ ۖ يَعْلَمُ سِرَّكُمْ وَجَهْرَكُمْ وَيَعْلَمُ مَا تَكْسِبُونَ","en":"And He is Allāh, [the only deity] in the heavens and the earth. He knows your secret and what you make public, and He knows that which you earn.","tr":"Wahuwa Allahu fee assamawatiwafee al-ardi yaAAlamu sirrakum wajahrakum wayaAAlamu mataksiboon","juz":7,"page":128},{"s":6,"a":4,"key":"6:4","ar":"وَمَا تَأْتِيهِم مِّنْ ءَايَةٍ مِّنْ ءَايَـٰتِ رَبِّهِمْ إِلَّا كَانُوا۟ عَنْهَا مُعْرِضِينَ","en":"And no sign comes to them from the signs of their Lord except that they turn away therefrom.","tr":"Wama ta/teehim min ayatin min ayatirabbihim illa kanoo AAanha muAArideen","juz":7,"page":128},{"s":6,"a":5,"key":"6:5","ar":"فَقَدْ كَذَّبُوا۟ بِٱلْحَقِّ لَمَّا جَآءَهُمْ ۖ فَسَوْفَ يَأْتِيهِمْ أَنۢبَـٰٓؤُا۟ مَا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"For they had denied the truth when it came to them, but there is going to reach them the news of what they used to ridicule.1","tr":"Faqad kaththaboo bilhaqqilamma jaahum fasawfa ya/teehim anbao makanoo bihi yastahzi-oon","juz":7,"page":128},{"s":6,"a":6,"key":"6:6","ar":"أَلَمْ يَرَوْا۟ كَمْ أَهْلَكْنَا مِن قَبْلِهِم مِّن قَرْنٍ مَّكَّنَّـٰهُمْ فِى ٱلْأَرْضِ مَا لَمْ نُمَكِّن لَّكُمْ وَأَرْسَلْنَا ٱلسَّمَآءَ عَلَيْهِم مِّدْرَارًا وَجَعَلْنَا ٱلْأَنْهَـٰرَ تَجْرِى مِن تَحْتِهِمْ فَأَهْلَكْنَـٰهُم بِذُنُوبِهِمْ وَأَنشَأْنَا مِنۢ بَعْدِهِمْ قَرْنًا ءَاخَرِينَ","en":"Have they not seen how many generations We destroyed before them which We had established upon the earth as We have not established you? And We sent [rain from] the sky upon them in showers and made rivers flow beneath them; then We destroyed them for their sins and brought forth after them a generation of others.","tr":"Alam yaraw kam ahlakna min qablihimmin qarnin makkannahum fee al-ardi ma lamnumakkin lakum waarsalna assamaa AAalayhimmidraran wajaAAalna al-anhara tajree min tahtihimfaahlaknahum bithunoobihim waansha/na minbaAAdihim qarnan akhareen","juz":7,"page":128},{"s":6,"a":7,"key":"6:7","ar":"وَلَوْ نَزَّلْنَا عَلَيْكَ كِتَـٰبًا فِى قِرْطَاسٍ فَلَمَسُوهُ بِأَيْدِيهِمْ لَقَالَ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ هَـٰذَآ إِلَّا سِحْرٌ مُّبِينٌ","en":"And even if We had sent down to you, [O Muḥammad], a written scripture on a page and they touched it with their hands, the disbelievers would say, \"This is not but obvious magic.\"","tr":"Walaw nazzalna AAalayka kitabanfee qirtasin falamasoohu bi-aydeehim laqala allatheenakafaroo in hatha illa sihrun mubeen","juz":7,"page":128},{"s":6,"a":8,"key":"6:8","ar":"وَقَالُوا۟ لَوْلَآ أُنزِلَ عَلَيْهِ مَلَكٌ ۖ وَلَوْ أَنزَلْنَا مَلَكًا لَّقُضِىَ ٱلْأَمْرُ ثُمَّ لَا يُنظَرُونَ","en":"And they say, \"Why was there not sent down to him an angel?\"1 But if We had sent down an angel, the matter would have been decided;2 then they would not be reprieved.","tr":"Waqaloo lawla onzila AAalayhimalakun walaw anzalna malakan laqudiya al-amruthumma la yuntharoon","juz":7,"page":128},{"s":6,"a":9,"key":"6:9","ar":"وَلَوْ جَعَلْنَـٰهُ مَلَكًا لَّجَعَلْنَـٰهُ رَجُلًا وَلَلَبَسْنَا عَلَيْهِم مَّا يَلْبِسُونَ","en":"And if We had made him [i.e., the messenger] an angel, We would have made him [appear as] a man, and We would have covered them with that in which they cover themselves [i.e., confusion and doubt].","tr":"Walaw jaAAalnahu malakan lajaAAalnahurajulan walalabasna AAalayhim ma yalbisoon","juz":7,"page":129},{"s":6,"a":10,"key":"6:10","ar":"وَلَقَدِ ٱسْتُهْزِئَ بِرُسُلٍ مِّن قَبْلِكَ فَحَاقَ بِٱلَّذِينَ سَخِرُوا۟ مِنْهُم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"And already were messengers ridiculed before you, but those who mocked them were enveloped by that which they used to ridicule.","tr":"Walaqadi istuhzi-a birusulin min qablika fahaqabillatheena sakhiroo minhum ma kanoobihi yastahzi-oon","juz":7,"page":129},{"s":6,"a":11,"key":"6:11","ar":"قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ ثُمَّ ٱنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُكَذِّبِينَ","en":"Say, \"Travel through the land; then observe how was the end of the deniers.\"","tr":"Qul seeroo fee al-ardi thumma onthurookayfa kana AAaqibatu almukaththibeen","juz":7,"page":129},{"s":6,"a":12,"key":"6:12","ar":"قُل لِّمَن مَّا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ قُل لِّلَّهِ ۚ كَتَبَ عَلَىٰ نَفْسِهِ ٱلرَّحْمَةَ ۚ لَيَجْمَعَنَّكُمْ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ لَا رَيْبَ فِيهِ ۚ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ فَهُمْ لَا يُؤْمِنُونَ","en":"Say, \"To whom belongs whatever is in the heavens and earth?\" Say, \"To Allāh.\" He has decreed upon Himself mercy. He will surely assemble you for the Day of Resurrection, about which there is no doubt. Those who will lose themselves [that Day] do not believe.","tr":"Qul liman ma fee assamawatiwal-ardi qul lillahi kataba AAalanafsihi arrahmata layajmaAAannakum ilayawmi alqiyamati la rayba feehi allatheenakhasiroo anfusahum fahum la yu/minoon","juz":7,"page":129},{"s":6,"a":13,"key":"6:13","ar":"۞ وَلَهُۥ مَا سَكَنَ فِى ٱلَّيْلِ وَٱلنَّهَارِ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"And to Him belongs that which reposes by night and by day, and He is the Hearing, the Knowing.","tr":"Walahu ma sakana fee allayli wannahariwahuwa assameeAAu alAAaleem","juz":7,"page":129},{"s":6,"a":14,"key":"6:14","ar":"قُلْ أَغَيْرَ ٱللَّهِ أَتَّخِذُ وَلِيًّا فَاطِرِ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَهُوَ يُطْعِمُ وَلَا يُطْعَمُ ۗ قُلْ إِنِّىٓ أُمِرْتُ أَنْ أَكُونَ أَوَّلَ مَنْ أَسْلَمَ ۖ وَلَا تَكُونَنَّ مِنَ ٱلْمُشْرِكِينَ","en":"Say, \"Is it other than Allāh I should take as a protector, Creator of the heavens and earth, while it is He who feeds and is not fed?\" Say, [O Muḥammad], \"Indeed, I have been commanded to be the first [among you] who submit [to Allāh] and [was commanded], 'Do not ever be of the polytheists.\"","tr":"Qul aghayra Allahi attakhithuwaliyyan fatiri assamawati wal-ardiwahuwa yutAAimu wala yutAAamu qul inneeomirtu an akoona awwala man aslama wala takoonanna minaalmushrikeen","juz":7,"page":129},{"s":6,"a":15,"key":"6:15","ar":"قُلْ إِنِّىٓ أَخَافُ إِنْ عَصَيْتُ رَبِّى عَذَابَ يَوْمٍ عَظِيمٍ","en":"Say, \"Indeed I fear, if I should disobey my Lord, the punishment of a tremendous Day.\"","tr":"Qul innee akhafu in AAasayturabbee AAathaba yawmin AAatheem","juz":7,"page":129},{"s":6,"a":16,"key":"6:16","ar":"مَّن يُصْرَفْ عَنْهُ يَوْمَئِذٍ فَقَدْ رَحِمَهُۥ ۚ وَذَٰلِكَ ٱلْفَوْزُ ٱلْمُبِينُ","en":"He from whom it is averted that Day - [Allāh] has granted him mercy. And that is the clear attainment.","tr":"Man yusraf AAanhu yawma-ithinfaqad rahimahu wathalika alfawzu almubeen","juz":7,"page":129},{"s":6,"a":17,"key":"6:17","ar":"وَإِن يَمْسَسْكَ ٱللَّهُ بِضُرٍّ فَلَا كَاشِفَ لَهُۥٓ إِلَّا هُوَ ۖ وَإِن يَمْسَسْكَ بِخَيْرٍ فَهُوَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"And if Allāh should touch you with adversity, there is no remover of it except Him. And if He touches you with good - then He is over all things competent.","tr":"Wa-in yamsaska Allahu bidurrinfala kashifa lahu illa huwa wa-in yamsaskabikhayrin fahuwa AAala kulli shay-in qadeer","juz":7,"page":129},{"s":6,"a":18,"key":"6:18","ar":"وَهُوَ ٱلْقَاهِرُ فَوْقَ عِبَادِهِۦ ۚ وَهُوَ ٱلْحَكِيمُ ٱلْخَبِيرُ","en":"And He is the subjugator over His servants. And He is the Wise,1 the Aware.2","tr":"Wahuwa alqahiru fawqa AAibadihiwahuwa alhakeemu alkhabeer","juz":7,"page":129},{"s":6,"a":19,"key":"6:19","ar":"قُلْ أَىُّ شَىْءٍ أَكْبَرُ شَهَـٰدَةً ۖ قُلِ ٱللَّهُ ۖ شَهِيدٌۢ بَيْنِى وَبَيْنَكُمْ ۚ وَأُوحِىَ إِلَىَّ هَـٰذَا ٱلْقُرْءَانُ لِأُنذِرَكُم بِهِۦ وَمَنۢ بَلَغَ ۚ أَئِنَّكُمْ لَتَشْهَدُونَ أَنَّ مَعَ ٱللَّهِ ءَالِهَةً أُخْرَىٰ ۚ قُل لَّآ أَشْهَدُ ۚ قُلْ إِنَّمَا هُوَ إِلَـٰهٌ وَٰحِدٌ وَإِنَّنِى بَرِىٓءٌ مِّمَّا تُشْرِكُونَ","en":"Say, \"What thing is greatest in testimony?\" Say, \"Allāh is witness between me and you. And this Qur’ān was revealed to me that I may warn you thereby and whomever it reaches.1 Do you [truly] testify that with Allāh there are other deities?\" Say, \"I will not testify [with you].\" Say, \"Indeed, He is but one God, and indeed, I am free of what you associate [with Him].\"","tr":"Qul ayyu shay-in akbaru shahadatanquli Allahu shaheedun baynee wabaynakum waoohiyailayya hatha alqur-anu li-onthirakum bihiwaman balagha a-innakum latashhadoona anna maAAa Allahi alihatanokhra qul la ashhadu qul innama huwa ilahunwahidun wa-innanee baree-on mimma tushrikoon","juz":7,"page":130},{"s":6,"a":20,"key":"6:20","ar":"ٱلَّذِينَ ءَاتَيْنَـٰهُمُ ٱلْكِتَـٰبَ يَعْرِفُونَهُۥ كَمَا يَعْرِفُونَ أَبْنَآءَهُمُ ۘ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ فَهُمْ لَا يُؤْمِنُونَ","en":"Those to whom We have given the Scripture recognize it1 as they recognize their [own] sons. Those who will lose themselves [in the Hereafter] do not believe.","tr":"Allatheena ataynahumualkitaba yaAArifoonahu kama yaAArifoona abnaahumallatheena khasiroo anfusahum fahum la yu/minoon","juz":7,"page":130},{"s":6,"a":21,"key":"6:21","ar":"وَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوْ كَذَّبَ بِـَٔايَـٰتِهِۦٓ ۗ إِنَّهُۥ لَا يُفْلِحُ ٱلظَّـٰلِمُونَ","en":"And who is more unjust than one who invents about Allāh a lie or denies His verses? Indeed, the wrongdoers will not succeed.","tr":"Waman athlamu mimmani iftaraAAala Allahi kathiban aw kaththababi-ayatihi innahu la yuflihu aththalimoon","juz":7,"page":130},{"s":6,"a":22,"key":"6:22","ar":"وَيَوْمَ نَحْشُرُهُمْ جَمِيعًا ثُمَّ نَقُولُ لِلَّذِينَ أَشْرَكُوٓا۟ أَيْنَ شُرَكَآؤُكُمُ ٱلَّذِينَ كُنتُمْ تَزْعُمُونَ","en":"And [mention, O Muḥammad], the Day We will gather them all together; then We will say to those who associated others with Allāh, \"Where are your 'partners' that you used to claim [with Him]?\"","tr":"Wayawma nahshuruhum jameeAAan thummanaqoolu lillatheena ashrakoo ayna shurakaokumu allatheenakuntum tazAAumoon","juz":7,"page":130},{"s":6,"a":23,"key":"6:23","ar":"ثُمَّ لَمْ تَكُن فِتْنَتُهُمْ إِلَّآ أَن قَالُوا۟ وَٱللَّهِ رَبِّنَا مَا كُنَّا مُشْرِكِينَ","en":"Then there will be no [excuse upon] examination except they will say, \"By Allāh, our Lord, we were not those who associated.\"","tr":"Thumma lam takun fitnatuhum illa an qaloowallahi rabbina ma kunnamushrikeen","juz":7,"page":130},{"s":6,"a":24,"key":"6:24","ar":"ٱنظُرْ كَيْفَ كَذَبُوا۟ عَلَىٰٓ أَنفُسِهِمْ ۚ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ","en":"See how they will lie about themselves. And lost from them will be what they used to invent.","tr":"Onthur kayfa kathabooAAala anfusihim wadalla AAanhum ma kanooyaftaroon","juz":7,"page":130},{"s":6,"a":25,"key":"6:25","ar":"وَمِنْهُم مَّن يَسْتَمِعُ إِلَيْكَ ۖ وَجَعَلْنَا عَلَىٰ قُلُوبِهِمْ أَكِنَّةً أَن يَفْقَهُوهُ وَفِىٓ ءَاذَانِهِمْ وَقْرًا ۚ وَإِن يَرَوْا۟ كُلَّ ءَايَةٍ لَّا يُؤْمِنُوا۟ بِهَا ۚ حَتَّىٰٓ إِذَا جَآءُوكَ يُجَـٰدِلُونَكَ يَقُولُ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ هَـٰذَآ إِلَّآ أَسَـٰطِيرُ ٱلْأَوَّلِينَ","en":"And among them are those who listen to you,1 but We have placed over their hearts coverings, lest they understand it, and in their ears deafness. And if they should see every sign, they will not believe in it. Even when they come to you arguing with you, those who disbelieve say, \"This is not but legends of the former peoples.\"","tr":"Waminhum man yastamiAAu ilayka wajaAAalnaAAala quloobihim akinnatan an yafqahoohu wafee athanihimwaqran wa-in yaraw kulla ayatin la yu/minoo bihahatta itha jaooka yujadiloonakayaqoolu allatheena kafaroo in hatha illa asateerual-awwaleen","juz":7,"page":130},{"s":6,"a":26,"key":"6:26","ar":"وَهُمْ يَنْهَوْنَ عَنْهُ وَيَنْـَٔوْنَ عَنْهُ ۖ وَإِن يُهْلِكُونَ إِلَّآ أَنفُسَهُمْ وَمَا يَشْعُرُونَ","en":"And they prevent [others] from him and are [themselves] remote from him. And they do not destroy except themselves, but they perceive [it] not.","tr":"Wahum yanhawna AAanhu wayan-awna AAanhuwa-in yuhlikoona illa anfusahum wama yashAAuroon","juz":7,"page":130},{"s":6,"a":27,"key":"6:27","ar":"وَلَوْ تَرَىٰٓ إِذْ وُقِفُوا۟ عَلَى ٱلنَّارِ فَقَالُوا۟ يَـٰلَيْتَنَا نُرَدُّ وَلَا نُكَذِّبَ بِـَٔايَـٰتِ رَبِّنَا وَنَكُونَ مِنَ ٱلْمُؤْمِنِينَ","en":"If you could but see when they are made to stand before the Fire and will say, \"Oh, would that we could be returned [to life on earth] and not deny the signs of our Lord and be among the believers.\"","tr":"Walaw tara ith wuqifoo AAalaannari faqaloo ya laytananuraddu wala nukaththiba bi-ayatirabbina wanakoona mina almu/mineen","juz":7,"page":130},{"s":6,"a":28,"key":"6:28","ar":"بَلْ بَدَا لَهُم مَّا كَانُوا۟ يُخْفُونَ مِن قَبْلُ ۖ وَلَوْ رُدُّوا۟ لَعَادُوا۟ لِمَا نُهُوا۟ عَنْهُ وَإِنَّهُمْ لَكَـٰذِبُونَ","en":"But what they concealed before has [now] appeared to them. And even if they were returned, they would return to that which they were forbidden; and indeed, they are liars.","tr":"Bal bada lahum ma kanooyukhfoona min qablu walaw ruddoo laAAadoo limanuhoo AAanhu wa-innahum lakathiboon","juz":7,"page":131},{"s":6,"a":29,"key":"6:29","ar":"وَقَالُوٓا۟ إِنْ هِىَ إِلَّا حَيَاتُنَا ٱلدُّنْيَا وَمَا نَحْنُ بِمَبْعُوثِينَ","en":"And they say, \"There is none but our worldly life, and we will not be resurrected.\"","tr":"Waqaloo in hiya illa hayatunaaddunya wama nahnu bimabAAootheen","juz":7,"page":131},{"s":6,"a":30,"key":"6:30","ar":"وَلَوْ تَرَىٰٓ إِذْ وُقِفُوا۟ عَلَىٰ رَبِّهِمْ ۚ قَالَ أَلَيْسَ هَـٰذَا بِٱلْحَقِّ ۚ قَالُوا۟ بَلَىٰ وَرَبِّنَا ۚ قَالَ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْفُرُونَ","en":"If you could but see when they will be made to stand before their Lord. He will say, \"Is this not the truth?\" They will say, \"Yes, by our Lord.\" He will [then] say, \"So taste the punishment for what you used to deny.\"","tr":"Walaw tara ith wuqifoo AAalarabbihim qala alaysa hatha bilhaqqiqaloo bala warabbina qala fathooqooalAAathaba bima kuntum takfuroon","juz":7,"page":131},{"s":6,"a":31,"key":"6:31","ar":"قَدْ خَسِرَ ٱلَّذِينَ كَذَّبُوا۟ بِلِقَآءِ ٱللَّهِ ۖ حَتَّىٰٓ إِذَا جَآءَتْهُمُ ٱلسَّاعَةُ بَغْتَةً قَالُوا۟ يَـٰحَسْرَتَنَا عَلَىٰ مَا فَرَّطْنَا فِيهَا وَهُمْ يَحْمِلُونَ أَوْزَارَهُمْ عَلَىٰ ظُهُورِهِمْ ۚ أَلَا سَآءَ مَا يَزِرُونَ","en":"Those will have lost who deny the meeting with Allāh, until when the Hour [of resurrection] comes upon them unexpectedly, they will say, \"Oh, [how great is] our regret over what we neglected concerning it [i.e., the Hour],\" while they bear their burdens [i.e., sins] on their backs. Unquestionably, evil is that which they bear.","tr":"Qad khasira allatheena kaththaboobiliqa-i Allahi hatta itha jaat-humuassaAAatu baghtatan qaloo ya hasratanaAAala ma farratna feeha wahumyahmiloona awzarahum AAala thuhoorihimala saa ma yaziroon","juz":7,"page":131},{"s":6,"a":32,"key":"6:32","ar":"وَمَا ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا لَعِبٌ وَلَهْوٌ ۖ وَلَلدَّارُ ٱلْـَٔاخِرَةُ خَيْرٌ لِّلَّذِينَ يَتَّقُونَ ۗ أَفَلَا تَعْقِلُونَ","en":"And the worldly life is not but amusement and diversion; but the home of the Hereafter is best for those who fear Allāh, so will you not reason?","tr":"Wama alhayatu addunyailla laAAibun walahwun waladdaru al-akhiratikhayrun lillatheena yattaqoona afala taAAqiloon","juz":7,"page":131},{"s":6,"a":33,"key":"6:33","ar":"قَدْ نَعْلَمُ إِنَّهُۥ لَيَحْزُنُكَ ٱلَّذِى يَقُولُونَ ۖ فَإِنَّهُمْ لَا يُكَذِّبُونَكَ وَلَـٰكِنَّ ٱلظَّـٰلِمِينَ بِـَٔايَـٰتِ ٱللَّهِ يَجْحَدُونَ","en":"We know that you, [O Muḥammad], are saddened by what they say. And indeed, they do not call you untruthful, but it is the verses of Allāh that the wrongdoers reject.","tr":"Qad naAAlamu innahu layahzunuka allatheeyaqooloona fa-innahum la yukaththiboonaka walakinnaaththalimeena bi-ayatiAllahi yajhadoon","juz":7,"page":131},{"s":6,"a":34,"key":"6:34","ar":"وَلَقَدْ كُذِّبَتْ رُسُلٌ مِّن قَبْلِكَ فَصَبَرُوا۟ عَلَىٰ مَا كُذِّبُوا۟ وَأُوذُوا۟ حَتَّىٰٓ أَتَىٰهُمْ نَصْرُنَا ۚ وَلَا مُبَدِّلَ لِكَلِمَـٰتِ ٱللَّهِ ۚ وَلَقَدْ جَآءَكَ مِن نَّبَإِى۟ ٱلْمُرْسَلِينَ","en":"And certainly were messengers denied before you, but they were patient over the denial, and they were harmed until Our victory came to them. And none can alter the words [i.e., decrees] of Allāh. And there has certainly come to you some information about the [previous] messengers.","tr":"Walaqad kuththibat rusulun minqablika fasabaroo AAala ma kuththiboowaoothoo hatta atahum nasrunawala mubaddila likalimati Allahi walaqad jaakamin naba-i almursaleen","juz":7,"page":131},{"s":6,"a":35,"key":"6:35","ar":"وَإِن كَانَ كَبُرَ عَلَيْكَ إِعْرَاضُهُمْ فَإِنِ ٱسْتَطَعْتَ أَن تَبْتَغِىَ نَفَقًا فِى ٱلْأَرْضِ أَوْ سُلَّمًا فِى ٱلسَّمَآءِ فَتَأْتِيَهُم بِـَٔايَةٍ ۚ وَلَوْ شَآءَ ٱللَّهُ لَجَمَعَهُمْ عَلَى ٱلْهُدَىٰ ۚ فَلَا تَكُونَنَّ مِنَ ٱلْجَـٰهِلِينَ","en":"And if their evasion is difficult for you, then if you are able to seek a tunnel into the earth or a stairway into the sky to bring them a sign, [then do so]. But if Allāh had willed, He would have united them upon guidance. So never be of the ignorant.","tr":"Wa-in kana kabura AAalayka iAAraduhumfa-ini istataAAta an tabtaghiya nafaqan fee al-ardiaw sullaman fee assama-i fata/tiyahum bi-ayatinwalaw shaa Allahu lajamaAAahum AAala alhudafala takoonanna mina aljahileen","juz":7,"page":131},{"s":6,"a":36,"key":"6:36","ar":"۞ إِنَّمَا يَسْتَجِيبُ ٱلَّذِينَ يَسْمَعُونَ ۘ وَٱلْمَوْتَىٰ يَبْعَثُهُمُ ٱللَّهُ ثُمَّ إِلَيْهِ يُرْجَعُونَ","en":"Only those who hear will respond. But the dead1 - Allāh will resurrect them; then to Him they will be returned.","tr":"Innama yastajeebu allatheenayasmaAAoona walmawta yabAAathuhumu Allahuthumma ilayhi yurjaAAoon","juz":7,"page":132},{"s":6,"a":37,"key":"6:37","ar":"وَقَالُوا۟ لَوْلَا نُزِّلَ عَلَيْهِ ءَايَةٌ مِّن رَّبِّهِۦ ۚ قُلْ إِنَّ ٱللَّهَ قَادِرٌ عَلَىٰٓ أَن يُنَزِّلَ ءَايَةً وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ","en":"And they say, \"Why has a sign not been sent down to him from his Lord?\" Say, \"Indeed, Allāh is Able to send down a sign, but most of them do not know.\"","tr":"Waqaloo lawla nuzzila AAalayhiayatun min rabbihi qul inna Allaha qadirunAAala an yunazzila ayatan walakinnaaktharahum la yaAAlamoon","juz":7,"page":132},{"s":6,"a":38,"key":"6:38","ar":"وَمَا مِن دَآبَّةٍ فِى ٱلْأَرْضِ وَلَا طَـٰٓئِرٍ يَطِيرُ بِجَنَاحَيْهِ إِلَّآ أُمَمٌ أَمْثَالُكُم ۚ مَّا فَرَّطْنَا فِى ٱلْكِتَـٰبِ مِن شَىْءٍ ۚ ثُمَّ إِلَىٰ رَبِّهِمْ يُحْشَرُونَ","en":"And there is no creature on [or within] the earth or bird that flies with its wings except [that they are] communities like you. We have not neglected in the Register1 a thing. Then unto their Lord they will be gathered.","tr":"Wama min dabbatin fee al-ardiwala ta-irin yateeru bijanahayhi illaomamun amthalukum ma farratna feealkitabi min shay-in thumma ila rabbihim yuhsharoon","juz":7,"page":132},{"s":6,"a":39,"key":"6:39","ar":"وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا صُمٌّ وَبُكْمٌ فِى ٱلظُّلُمَـٰتِ ۗ مَن يَشَإِ ٱللَّهُ يُضْلِلْهُ وَمَن يَشَأْ يَجْعَلْهُ عَلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"But those who deny Our verses are deaf and dumb within darknesses. Whomever Allāh wills - He sends astray; and whomever He wills - He puts him on a straight path.","tr":"Wallatheena kaththaboobi-ayatina summun wabukmun fee aththulumatiman yasha-i Allahu yudlilhu waman yasha/ yajAAalhuAAala siratin mustaqeem","juz":7,"page":132},{"s":6,"a":40,"key":"6:40","ar":"قُلْ أَرَءَيْتَكُمْ إِنْ أَتَىٰكُمْ عَذَابُ ٱللَّهِ أَوْ أَتَتْكُمُ ٱلسَّاعَةُ أَغَيْرَ ٱللَّهِ تَدْعُونَ إِن كُنتُمْ صَـٰدِقِينَ","en":"Say, \"Have you considered:1 if there came to you the punishment of Allāh or there came to you the Hour - is it other than Allāh you would invoke, if you should be truthful?\"","tr":"Qul araaytakum in atakum AAathabuAllahi aw atatkumu assaAAatu aghayra AllahitadAAoona in kuntum sadiqeen","juz":7,"page":132},{"s":6,"a":41,"key":"6:41","ar":"بَلْ إِيَّاهُ تَدْعُونَ فَيَكْشِفُ مَا تَدْعُونَ إِلَيْهِ إِن شَآءَ وَتَنسَوْنَ مَا تُشْرِكُونَ","en":"No, it is Him [alone] you would invoke, and He would remove that for which you invoked Him if He willed, and you would forget what you associate [with Him].","tr":"Bal iyyahu tadAAoona fayakshifu matadAAoona ilayhi in shaa watansawna ma tushrikoon","juz":7,"page":132},{"s":6,"a":42,"key":"6:42","ar":"وَلَقَدْ أَرْسَلْنَآ إِلَىٰٓ أُمَمٍ مِّن قَبْلِكَ فَأَخَذْنَـٰهُم بِٱلْبَأْسَآءِ وَٱلضَّرَّآءِ لَعَلَّهُمْ يَتَضَرَّعُونَ","en":"And We have already sent [messengers] to nations before you, [O Muḥammad]; then We seized them with poverty and hardship that perhaps they might humble themselves [to Us].","tr":"Walaqad arsalna ila omamin minqablika faakhathnahum bilba/sa-i waddarra-ilaAAallahum yatadarraAAoon","juz":7,"page":132},{"s":6,"a":43,"key":"6:43","ar":"فَلَوْلَآ إِذْ جَآءَهُم بَأْسُنَا تَضَرَّعُوا۟ وَلَـٰكِن قَسَتْ قُلُوبُهُمْ وَزَيَّنَ لَهُمُ ٱلشَّيْطَـٰنُ مَا كَانُوا۟ يَعْمَلُونَ","en":"Then why, when Our punishment came to them, did they not humble themselves? But their hearts became hardened, and Satan made attractive to them that which they were doing.","tr":"Falawla ith jaahumba/suna tadarraAAoo walakin qasat quloobuhumwazayyana lahumu ashshaytanu ma kanooyaAAmaloon","juz":7,"page":132},{"s":6,"a":44,"key":"6:44","ar":"فَلَمَّا نَسُوا۟ مَا ذُكِّرُوا۟ بِهِۦ فَتَحْنَا عَلَيْهِمْ أَبْوَٰبَ كُلِّ شَىْءٍ حَتَّىٰٓ إِذَا فَرِحُوا۟ بِمَآ أُوتُوٓا۟ أَخَذْنَـٰهُم بَغْتَةً فَإِذَا هُم مُّبْلِسُونَ","en":"So when they forgot that by which they had been reminded,1 We opened to them the doors of every [good] thing until, when they rejoiced in that which they were given, We seized them suddenly, and they were [then] in despair.","tr":"Falamma nasoo ma thukkiroobihi fatahna AAalayhim abwaba kulli shay-in hattaitha farihoo bima ootoo akhathnahumbaghtatan fa-itha hum mublisoon","juz":7,"page":132},{"s":6,"a":45,"key":"6:45","ar":"فَقُطِعَ دَابِرُ ٱلْقَوْمِ ٱلَّذِينَ ظَلَمُوا۟ ۚ وَٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَـٰلَمِينَ","en":"So the people that committed wrong were eliminated. And praise to Allāh, Lord of the worlds.","tr":"FaqutiAAa dabiru alqawmi allatheenathalamoo walhamdu lillahirabbi alAAalameen","juz":7,"page":133},{"s":6,"a":46,"key":"6:46","ar":"قُلْ أَرَءَيْتُمْ إِنْ أَخَذَ ٱللَّهُ سَمْعَكُمْ وَأَبْصَـٰرَكُمْ وَخَتَمَ عَلَىٰ قُلُوبِكُم مَّنْ إِلَـٰهٌ غَيْرُ ٱللَّهِ يَأْتِيكُم بِهِ ۗ ٱنظُرْ كَيْفَ نُصَرِّفُ ٱلْـَٔايَـٰتِ ثُمَّ هُمْ يَصْدِفُونَ","en":"Say, \"Have you considered:1 if Allāh should take away your hearing and your sight and set a seal upon your hearts, which deity other than Allāh could bring them [back] to you?\" Look how We diversify2 the verses; then they [still] turn away.","tr":"Qul araaytum in akhatha AllahusamAAakum waabsarakum wakhatama AAala quloobikumman ilahun ghayru Allahi ya/teekum bihi onthurkayfa nusarrifu al-ayati thumma hum yasdifoon","juz":7,"page":133},{"s":6,"a":47,"key":"6:47","ar":"قُلْ أَرَءَيْتَكُمْ إِنْ أَتَىٰكُمْ عَذَابُ ٱللَّهِ بَغْتَةً أَوْ جَهْرَةً هَلْ يُهْلَكُ إِلَّا ٱلْقَوْمُ ٱلظَّـٰلِمُونَ","en":"Say, \"Have you considered: if the punishment of Allāh should come to you unexpectedly or manifestly,1 will any be destroyed but the wrongdoing people?\"","tr":"Qul araaytakum in atakum AAathabuAllahi baghtatan aw jahratan hal yuhlaku illaalqawmu aththalimoon","juz":7,"page":133},{"s":6,"a":48,"key":"6:48","ar":"وَمَا نُرْسِلُ ٱلْمُرْسَلِينَ إِلَّا مُبَشِّرِينَ وَمُنذِرِينَ ۖ فَمَنْ ءَامَنَ وَأَصْلَحَ فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"And We send not the messengers except as bringers of good tidings and warners. So whoever believes and reforms - there will be no fear concerning them, nor will they grieve.","tr":"Wama nursilu almursaleena illamubashshireena wamunthireena faman amana waaslahafala khawfun AAalayhim wala hum yahzanoon","juz":7,"page":133},{"s":6,"a":49,"key":"6:49","ar":"وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا يَمَسُّهُمُ ٱلْعَذَابُ بِمَا كَانُوا۟ يَفْسُقُونَ","en":"But those who deny Our verses - the punishment will touch1 them for their defiant disobedience.","tr":"Wallatheena kaththaboobi-ayatina yamassuhumu alAAathabu bimakanoo yafsuqoon","juz":7,"page":133},{"s":6,"a":50,"key":"6:50","ar":"قُل لَّآ أَقُولُ لَكُمْ عِندِى خَزَآئِنُ ٱللَّهِ وَلَآ أَعْلَمُ ٱلْغَيْبَ وَلَآ أَقُولُ لَكُمْ إِنِّى مَلَكٌ ۖ إِنْ أَتَّبِعُ إِلَّا مَا يُوحَىٰٓ إِلَىَّ ۚ قُلْ هَلْ يَسْتَوِى ٱلْأَعْمَىٰ وَٱلْبَصِيرُ ۚ أَفَلَا تَتَفَكَّرُونَ","en":"Say, [O Muḥammad], \"I do not tell you that I have the depositories [containing the provision] of Allāh or that I know the unseen, nor do I tell you that I am an angel. I only follow what is revealed to me.\" Say, \"Is the blind equivalent to the seeing? Then will you not give thought?\"","tr":"Qul la aqoolu lakum AAindee khaza-inuAllahi wala aAAlamu alghayba wala aqoolulakum innee malakun in attabiAAu illa ma yoohailayya qul hal yastawee al-aAAma walbaseeruafala tatafakkaroon","juz":7,"page":133},{"s":6,"a":51,"key":"6:51","ar":"وَأَنذِرْ بِهِ ٱلَّذِينَ يَخَافُونَ أَن يُحْشَرُوٓا۟ إِلَىٰ رَبِّهِمْ ۙ لَيْسَ لَهُم مِّن دُونِهِۦ وَلِىٌّ وَلَا شَفِيعٌ لَّعَلَّهُمْ يَتَّقُونَ","en":"And warn by it [i.e., the Qur’ān] those who fear that they will be gathered before their Lord - for them besides Him will be no protector and no intercessor - that they might become righteous.","tr":"Waanthir bihi allatheena yakhafoonaan yuhsharoo ila rabbihim laysa lahum min doonihiwaliyyun wala shafeeAAun laAAallahum yattaqoon","juz":7,"page":133},{"s":6,"a":52,"key":"6:52","ar":"وَلَا تَطْرُدِ ٱلَّذِينَ يَدْعُونَ رَبَّهُم بِٱلْغَدَوٰةِ وَٱلْعَشِىِّ يُرِيدُونَ وَجْهَهُۥ ۖ مَا عَلَيْكَ مِنْ حِسَابِهِم مِّن شَىْءٍ وَمَا مِنْ حِسَابِكَ عَلَيْهِم مِّن شَىْءٍ فَتَطْرُدَهُمْ فَتَكُونَ مِنَ ٱلظَّـٰلِمِينَ","en":"And do not send away those who call upon their Lord morning and afternoon, seeking His face [i.e., favor]. Not upon you is anything of their account and not upon them is anything of your account.1 So were you to send them away, you would [then] be of the wrongdoers.","tr":"Wala tatrudi allatheenayadAAoona rabbahum bilghadati walAAashiyyiyureedoona wajhahu ma AAalayka min hisabihimmin shay-in wama min hisabika AAalayhim minshay-in fatatrudahum fatakoona mina aththalimeen","juz":7,"page":133},{"s":6,"a":53,"key":"6:53","ar":"وَكَذَٰلِكَ فَتَنَّا بَعْضَهُم بِبَعْضٍ لِّيَقُولُوٓا۟ أَهَـٰٓؤُلَآءِ مَنَّ ٱللَّهُ عَلَيْهِم مِّنۢ بَيْنِنَآ ۗ أَلَيْسَ ٱللَّهُ بِأَعْلَمَ بِٱلشَّـٰكِرِينَ","en":"And thus We have tried some of them through others that they [i.e., the disbelievers] might say, \"Is it these whom Allāh has favored among us?\" Is not Allāh most knowing of those who are grateful?1","tr":"Wakathalika fatanna baAAdahumbibaAAdin liyaqooloo ahaola-i manna AllahuAAalayhim min baynina alaysa Allahu bi-aAAlama bishshakireen","juz":7,"page":134},{"s":6,"a":54,"key":"6:54","ar":"وَإِذَا جَآءَكَ ٱلَّذِينَ يُؤْمِنُونَ بِـَٔايَـٰتِنَا فَقُلْ سَلَـٰمٌ عَلَيْكُمْ ۖ كَتَبَ رَبُّكُمْ عَلَىٰ نَفْسِهِ ٱلرَّحْمَةَ ۖ أَنَّهُۥ مَنْ عَمِلَ مِنكُمْ سُوٓءًۢا بِجَهَـٰلَةٍ ثُمَّ تَابَ مِنۢ بَعْدِهِۦ وَأَصْلَحَ فَأَنَّهُۥ غَفُورٌ رَّحِيمٌ","en":"And when those come to you who believe in Our verses, say, \"Peace be upon you. Your Lord has decreed upon Himself mercy: that any of you who does wrong out of ignorance and then repents after that and corrects himself - indeed, He is Forgiving and Merciful.\"","tr":"Wa-itha jaaka allatheenayu/minoona bi-ayatina faqul salamunAAalaykum kataba rabbukum AAala nafsihi arrahmataannahu man AAamila minkum soo-an bijahalatin thumma tabamin baAAdihi waaslaha faannahu ghafoorun raheem","juz":7,"page":134},{"s":6,"a":55,"key":"6:55","ar":"وَكَذَٰلِكَ نُفَصِّلُ ٱلْـَٔايَـٰتِ وَلِتَسْتَبِينَ سَبِيلُ ٱلْمُجْرِمِينَ","en":"And thus do We detail the verses, and [thus] the way of the criminals will become evident.","tr":"Wakathalika nufassilu al-ayatiwalitastabeena sabeelu almujrimeen","juz":7,"page":134},{"s":6,"a":56,"key":"6:56","ar":"قُلْ إِنِّى نُهِيتُ أَنْ أَعْبُدَ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ ۚ قُل لَّآ أَتَّبِعُ أَهْوَآءَكُمْ ۙ قَدْ ضَلَلْتُ إِذًا وَمَآ أَنَا۠ مِنَ ٱلْمُهْتَدِينَ","en":"Say, \"Indeed, I have been forbidden to worship those you invoke besides Allāh.\" Say, \"I will not follow your desires, for I would then have gone astray, and I would not be of the [rightly] guided.\"","tr":"Qul innee nuheetu an aAAbuda allatheenatadAAoona min dooni Allahi qul la attabiAAu ahwaakumqad dalaltu ithan wama ana minaalmuhtadeen","juz":7,"page":134},{"s":6,"a":57,"key":"6:57","ar":"قُلْ إِنِّى عَلَىٰ بَيِّنَةٍ مِّن رَّبِّى وَكَذَّبْتُم بِهِۦ ۚ مَا عِندِى مَا تَسْتَعْجِلُونَ بِهِۦٓ ۚ إِنِ ٱلْحُكْمُ إِلَّا لِلَّهِ ۖ يَقُصُّ ٱلْحَقَّ ۖ وَهُوَ خَيْرُ ٱلْفَـٰصِلِينَ","en":"Say, \"Indeed, I am on clear evidence from my Lord, and you have denied it. I do not have that for which you are impatient.1 The decision is only for Allāh. He relates the truth, and He is the best of deciders.\"","tr":"Qul innee AAala bayyinatin min rabbeewakaththabtum bihi ma AAindee matastaAAjiloona bihi ini alhukmu illa lillahiyaqussu alhaqqa wahuwa khayru alfasileen","juz":7,"page":134},{"s":6,"a":58,"key":"6:58","ar":"قُل لَّوْ أَنَّ عِندِى مَا تَسْتَعْجِلُونَ بِهِۦ لَقُضِىَ ٱلْأَمْرُ بَيْنِى وَبَيْنَكُمْ ۗ وَٱللَّهُ أَعْلَمُ بِٱلظَّـٰلِمِينَ","en":"Say, \"If I had that for which you are impatient, the matter would have been decided between me and you, but Allāh is most knowing of the wrongdoers.\"","tr":"Qul law anna AAindee matastaAAjiloona bihi laqudiya al-amru baynee wabaynakum wallahuaAAlamu biththalimeen","juz":7,"page":134},{"s":6,"a":59,"key":"6:59","ar":"۞ وَعِندَهُۥ مَفَاتِحُ ٱلْغَيْبِ لَا يَعْلَمُهَآ إِلَّا هُوَ ۚ وَيَعْلَمُ مَا فِى ٱلْبَرِّ وَٱلْبَحْرِ ۚ وَمَا تَسْقُطُ مِن وَرَقَةٍ إِلَّا يَعْلَمُهَا وَلَا حَبَّةٍ فِى ظُلُمَـٰتِ ٱلْأَرْضِ وَلَا رَطْبٍ وَلَا يَابِسٍ إِلَّا فِى كِتَـٰبٍ مُّبِينٍ","en":"And with Him are the keys of the unseen; none knows them except Him. And He knows what is on the land and in the sea. Not a leaf falls but that He knows it. And no grain is there within the darknesses of the earth and no moist or dry [thing] but that it is [written] in a clear record.","tr":"WaAAindahu mafatihu alghaybi layaAAlamuha illa huwa wayaAAlamu ma feealbarri walbahri wama tasqutu minwaraqatin illa yaAAlamuha wala habbatinfee thulumati al-ardi wala ratbinwala yabisin illa fee kitabin mubeen","juz":7,"page":134},{"s":6,"a":60,"key":"6:60","ar":"وَهُوَ ٱلَّذِى يَتَوَفَّىٰكُم بِٱلَّيْلِ وَيَعْلَمُ مَا جَرَحْتُم بِٱلنَّهَارِ ثُمَّ يَبْعَثُكُمْ فِيهِ لِيُقْضَىٰٓ أَجَلٌ مُّسَمًّى ۖ ثُمَّ إِلَيْهِ مَرْجِعُكُمْ ثُمَّ يُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ","en":"And it is He who takes your souls by night1 and knows what you have committed by day. Then He revives you therein [i.e., by day] that a specified term2 may be fulfilled. Then to Him will be your return; then He will inform you about what you used to do.","tr":"Wahuwa allathee yatawaffakumbillayli wayaAAlamu ma jarahtum binnaharithumma yabAAathukum feehi liyuqda ajalun musamman thummailayhi marjiAAukum thumma yunabbi-okum bima kuntumtaAAmaloon","juz":7,"page":135},{"s":6,"a":61,"key":"6:61","ar":"وَهُوَ ٱلْقَاهِرُ فَوْقَ عِبَادِهِۦ ۖ وَيُرْسِلُ عَلَيْكُمْ حَفَظَةً حَتَّىٰٓ إِذَا جَآءَ أَحَدَكُمُ ٱلْمَوْتُ تَوَفَّتْهُ رُسُلُنَا وَهُمْ لَا يُفَرِّطُونَ","en":"And He is the subjugator over His servants, and He sends over you guardian-angels until, when death comes to one of you, Our messengers [i.e., angels of death] take him, and they do not fail [in their duties].","tr":"Wahuwa alqahiru fawqa AAibadihiwayursilu AAalaykum hafathatan hattaitha jaa ahadakumu almawtu tawaffat-hurusuluna wahum la yufarritoon","juz":7,"page":135},{"s":6,"a":62,"key":"6:62","ar":"ثُمَّ رُدُّوٓا۟ إِلَى ٱللَّهِ مَوْلَىٰهُمُ ٱلْحَقِّ ۚ أَلَا لَهُ ٱلْحُكْمُ وَهُوَ أَسْرَعُ ٱلْحَـٰسِبِينَ","en":"Then they [i.e., His servants] are returned to Allāh, their true Lord. Unquestionably, His is the judgement, and He is the swiftest of accountants.","tr":"Thumma ruddoo ila Allahi mawlahumualhaqqi ala lahu alhukmu wahuwa asraAAu alhasibeen","juz":7,"page":135},{"s":6,"a":63,"key":"6:63","ar":"قُلْ مَن يُنَجِّيكُم مِّن ظُلُمَـٰتِ ٱلْبَرِّ وَٱلْبَحْرِ تَدْعُونَهُۥ تَضَرُّعًا وَخُفْيَةً لَّئِنْ أَنجَىٰنَا مِنْ هَـٰذِهِۦ لَنَكُونَنَّ مِنَ ٱلشَّـٰكِرِينَ","en":"Say, \"Who rescues you from the darknesses of the land and sea [when] you call upon Him imploring [aloud] and privately, 'If He should save us from this [crisis], we will surely be among the thankful.'\"","tr":"Qul man yunajjeekum min thulumatialbarri walbahri tadAAoonahu tadarruAAanwakhufyatan la-in anjana min hathihilanakoonanna mina ashshakireen","juz":7,"page":135},{"s":6,"a":64,"key":"6:64","ar":"قُلِ ٱللَّهُ يُنَجِّيكُم مِّنْهَا وَمِن كُلِّ كَرْبٍ ثُمَّ أَنتُمْ تُشْرِكُونَ","en":"Say, \"It is Allāh who saves you from it and from every distress; then you [still] associate others with Him.\"","tr":"Quli Allahu yunajjeekum minhawamin kulli karbin thumma antum tushrikoon","juz":7,"page":135},{"s":6,"a":65,"key":"6:65","ar":"قُلْ هُوَ ٱلْقَادِرُ عَلَىٰٓ أَن يَبْعَثَ عَلَيْكُمْ عَذَابًا مِّن فَوْقِكُمْ أَوْ مِن تَحْتِ أَرْجُلِكُمْ أَوْ يَلْبِسَكُمْ شِيَعًا وَيُذِيقَ بَعْضَكُم بَأْسَ بَعْضٍ ۗ ٱنظُرْ كَيْفَ نُصَرِّفُ ٱلْـَٔايَـٰتِ لَعَلَّهُمْ يَفْقَهُونَ","en":"Say, \"He is the [one] Able to send upon you affliction from above you or from beneath your feet or to confuse you [so you become] sects1 and make you taste the violence of one another.\" Look how We diversify the signs that they might understand.","tr":"Qul huwa alqadiru AAala anyabAAatha AAalaykum AAathaban min fawqikum aw min tahtiarjulikum aw yalbisakum shiyaAAan wayutheeqa baAAdakumba/sa baAAdin onthur kayfa nusarrifual-ayati laAAallahum yafqahoon","juz":7,"page":135},{"s":6,"a":66,"key":"6:66","ar":"وَكَذَّبَ بِهِۦ قَوْمُكَ وَهُوَ ٱلْحَقُّ ۚ قُل لَّسْتُ عَلَيْكُم بِوَكِيلٍ","en":"But your people have denied it while it is the truth. Say, \"I am not over you a manager [i.e., authority].\"","tr":"Wakaththaba bihi qawmuka wahuwa alhaqququl lastu AAalaykum biwakeel","juz":7,"page":135},{"s":6,"a":67,"key":"6:67","ar":"لِّكُلِّ نَبَإٍ مُّسْتَقَرٌّ ۚ وَسَوْفَ تَعْلَمُونَ","en":"For every news [i.e., happening] is a finality;1 and you are going to know.","tr":"Likulli naba-in mustaqarrun wasawfataAAlamoon","juz":7,"page":135},{"s":6,"a":68,"key":"6:68","ar":"وَإِذَا رَأَيْتَ ٱلَّذِينَ يَخُوضُونَ فِىٓ ءَايَـٰتِنَا فَأَعْرِضْ عَنْهُمْ حَتَّىٰ يَخُوضُوا۟ فِى حَدِيثٍ غَيْرِهِۦ ۚ وَإِمَّا يُنسِيَنَّكَ ٱلشَّيْطَـٰنُ فَلَا تَقْعُدْ بَعْدَ ٱلذِّكْرَىٰ مَعَ ٱلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"And when you see those who engage in [offensive] discourse1 concerning Our verses, then turn away from them until they enter into another conversation. And if Satan should cause you to forget, then do not remain after the reminder with the wrongdoing people.","tr":"Wa-itha raayta allatheenayakhoodoona fee ayatina faaAAridAAanhum hatta yakhoodoo fee hadeethinghayrihi wa-imma yunsiyannaka ashshaytanufala taqAAud baAAda aththikra maAAaalqawmi aththalimeen","juz":7,"page":135},{"s":6,"a":69,"key":"6:69","ar":"وَمَا عَلَى ٱلَّذِينَ يَتَّقُونَ مِنْ حِسَابِهِم مِّن شَىْءٍ وَلَـٰكِن ذِكْرَىٰ لَعَلَّهُمْ يَتَّقُونَ","en":"And those who fear Allāh are not held accountable for them [i.e., the disbelievers] at all, but [only for] a reminder - that perhaps they will fear Him.","tr":"Wama AAala allatheenayattaqoona min hisabihim min shay-in walakinthikra laAAallahum yattaqoon","juz":7,"page":136},{"s":6,"a":70,"key":"6:70","ar":"وَذَرِ ٱلَّذِينَ ٱتَّخَذُوا۟ دِينَهُمْ لَعِبًا وَلَهْوًا وَغَرَّتْهُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا ۚ وَذَكِّرْ بِهِۦٓ أَن تُبْسَلَ نَفْسٌۢ بِمَا كَسَبَتْ لَيْسَ لَهَا مِن دُونِ ٱللَّهِ وَلِىٌّ وَلَا شَفِيعٌ وَإِن تَعْدِلْ كُلَّ عَدْلٍ لَّا يُؤْخَذْ مِنْهَآ ۗ أُو۟لَـٰٓئِكَ ٱلَّذِينَ أُبْسِلُوا۟ بِمَا كَسَبُوا۟ ۖ لَهُمْ شَرَابٌ مِّنْ حَمِيمٍ وَعَذَابٌ أَلِيمٌۢ بِمَا كَانُوا۟ يَكْفُرُونَ","en":"And leave those who take their religion as amusement and diversion and whom the worldly life has deluded. But remind with it [i.e., the Qur’ān], lest a soul be given up to destruction for what it earned; it will have other than Allāh no protector and no intercessor. And if it should offer every compensation, it would not be taken from it [i.e., that soul]. Those are the ones who are given to destruction for what they have earned. For them will be a drink of scalding water and a painful punishment because they used to disbelieve.","tr":"Wathari allatheena ittakhathoodeenahum laAAiban walahwan wagharrat-humu alhayatuaddunya wathakkir bihi an tubsala nafsunbima kasabat laysa laha min dooni Allahiwaliyyun wala shafeeAAun wa-in taAAdil kulla AAadlin layu/khath minha ola-ika allatheenaobsiloo bima kasaboo lahum sharabun min hameeminwaAAathabun aleemun bima kanoo yakfuroon","juz":7,"page":136},{"s":6,"a":71,"key":"6:71","ar":"قُلْ أَنَدْعُوا۟ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُنَا وَلَا يَضُرُّنَا وَنُرَدُّ عَلَىٰٓ أَعْقَابِنَا بَعْدَ إِذْ هَدَىٰنَا ٱللَّهُ كَٱلَّذِى ٱسْتَهْوَتْهُ ٱلشَّيَـٰطِينُ فِى ٱلْأَرْضِ حَيْرَانَ لَهُۥٓ أَصْحَـٰبٌ يَدْعُونَهُۥٓ إِلَى ٱلْهُدَى ٱئْتِنَا ۗ قُلْ إِنَّ هُدَى ٱللَّهِ هُوَ ٱلْهُدَىٰ ۖ وَأُمِرْنَا لِنُسْلِمَ لِرَبِّ ٱلْعَـٰلَمِينَ","en":"Say, \"Shall we invoke1 instead of Allāh that which neither benefits us nor harms us and be turned back on our heels after Allāh has guided us? [We would then be] like one whom the devils enticed [to wander] upon the earth confused, [while] he has companions inviting him to guidance, [calling], 'Come to us.'\"2 Say, \"Indeed, the guidance of Allāh is the [only] guidance; and we have been commanded to submit to the Lord of the worlds.","tr":"Qul anadAAoo min dooni Allahi mala yanfaAAuna wala yadurrunawanuraddu AAala aAAqabina baAAda ithhadana Allahu kallathee istahwat-huashshayateenu fee al-ardi hayranalahu as-habun yadAAoonahu ila alhudai/tina qul inna huda Allahi huwa alhudawaomirna linuslima lirabbi alAAalameen","juz":7,"page":136},{"s":6,"a":72,"key":"6:72","ar":"وَأَنْ أَقِيمُوا۟ ٱلصَّلَوٰةَ وَٱتَّقُوهُ ۚ وَهُوَ ٱلَّذِىٓ إِلَيْهِ تُحْشَرُونَ","en":"And to establish prayer and fear Him.\" And it is He to whom you will be gathered.","tr":"Waan aqeemoo assalatawattaqoohu wahuwa allathee ilayhi tuhsharoon","juz":7,"page":136},{"s":6,"a":73,"key":"6:73","ar":"وَهُوَ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۖ وَيَوْمَ يَقُولُ كُن فَيَكُونُ ۚ قَوْلُهُ ٱلْحَقُّ ۚ وَلَهُ ٱلْمُلْكُ يَوْمَ يُنفَخُ فِى ٱلصُّورِ ۚ عَـٰلِمُ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ ۚ وَهُوَ ٱلْحَكِيمُ ٱلْخَبِيرُ","en":"And it is He who created the heavens and earth in truth. And the day [i.e., whenever] He says, \"Be,\" and it is, His word is the truth.1 And His is the dominion [on] the Day the Horn is blown. [He is] Knower of the unseen2 and the witnessed;3 and He is the Wise, the Aware.","tr":"Wahuwa allathee khalaqa assamawatiwal-arda bilhaqqi wayawma yaqoolukun fayakoonu qawluhu alhaqqu walahu almulku yawmayunfakhu fee assoori AAalimu alghaybi washshahadatiwahuwa alhakeemu alkhabeer","juz":7,"page":136},{"s":6,"a":74,"key":"6:74","ar":"۞ وَإِذْ قَالَ إِبْرَٰهِيمُ لِأَبِيهِ ءَازَرَ أَتَتَّخِذُ أَصْنَامًا ءَالِهَةً ۖ إِنِّىٓ أَرَىٰكَ وَقَوْمَكَ فِى ضَلَـٰلٍ مُّبِينٍ","en":"And [mention, O Muḥammad], when Abraham said to his father Āzar, \"Do you take idols as deities? Indeed, I see you and your people to be in manifest error.\"","tr":"Wa-ith qala ibraheemuli-abeehi azara atattakhithu asnaman alihataninnee araka waqawmaka fee dalalin mubeen","juz":7,"page":137},{"s":6,"a":75,"key":"6:75","ar":"وَكَذَٰلِكَ نُرِىٓ إِبْرَٰهِيمَ مَلَكُوتَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَلِيَكُونَ مِنَ ٱلْمُوقِنِينَ","en":"And thus did We show Abraham the realm of the heavens and the earth that he would be among the certain [in faith].","tr":"Wakathalika nuree ibraheemamalakoota assamawati wal-ardiwaliyakoona mina almooqineen","juz":7,"page":137},{"s":6,"a":76,"key":"6:76","ar":"فَلَمَّا جَنَّ عَلَيْهِ ٱلَّيْلُ رَءَا كَوْكَبًا ۖ قَالَ هَـٰذَا رَبِّى ۖ فَلَمَّآ أَفَلَ قَالَ لَآ أُحِبُّ ٱلْـَٔافِلِينَ","en":"So when the night covered him [with darkness], he saw a star. He said, \"This is my lord.\"1 But when it set, he said, \"I like not those that set [i.e., disappear].\"","tr":"Falamma janna AAalayhi allaylu raakawkaban qala hatha rabbee falamma afala qalala ohibbu al-afileen","juz":7,"page":137},{"s":6,"a":77,"key":"6:77","ar":"فَلَمَّا رَءَا ٱلْقَمَرَ بَازِغًا قَالَ هَـٰذَا رَبِّى ۖ فَلَمَّآ أَفَلَ قَالَ لَئِن لَّمْ يَهْدِنِى رَبِّى لَأَكُونَنَّ مِنَ ٱلْقَوْمِ ٱلضَّآلِّينَ","en":"And when he saw the moon rising, he said, \"This is my lord.\" But when it set, he said, \"Unless my Lord guides me, I will surely be among the people gone astray.\"","tr":"Falamma raa alqamara bazighanqala hatha rabbee falamma afala qalala-in lam yahdinee rabbee laakoonanna mina alqawmi addalleen","juz":7,"page":137},{"s":6,"a":78,"key":"6:78","ar":"فَلَمَّا رَءَا ٱلشَّمْسَ بَازِغَةً قَالَ هَـٰذَا رَبِّى هَـٰذَآ أَكْبَرُ ۖ فَلَمَّآ أَفَلَتْ قَالَ يَـٰقَوْمِ إِنِّى بَرِىٓءٌ مِّمَّا تُشْرِكُونَ","en":"And when he saw the sun rising, he said, \"This is my lord; this is greater.\" But when it set, he said, \"O my people, indeed I am free from what you associate with Allāh.","tr":"Falamma raa ashshamsabazighatan qala hatha rabbee hathaakbaru falamma afalat qala ya qawmi inneebaree-on mimma tushrikoon","juz":7,"page":137},{"s":6,"a":79,"key":"6:79","ar":"إِنِّى وَجَّهْتُ وَجْهِىَ لِلَّذِى فَطَرَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ حَنِيفًا ۖ وَمَآ أَنَا۠ مِنَ ٱلْمُشْرِكِينَ","en":"Indeed, I have turned my face [i.e., self] toward He who created the heavens and the earth, inclining toward truth, and I am not of those who associate others with Allāh.\"","tr":"Innee wajjahtu wajhiya lillathee fataraassamawati wal-arda haneefanwama ana mina almushrikeen","juz":7,"page":137},{"s":6,"a":80,"key":"6:80","ar":"وَحَآجَّهُۥ قَوْمُهُۥ ۚ قَالَ أَتُحَـٰٓجُّوٓنِّى فِى ٱللَّهِ وَقَدْ هَدَىٰنِ ۚ وَلَآ أَخَافُ مَا تُشْرِكُونَ بِهِۦٓ إِلَّآ أَن يَشَآءَ رَبِّى شَيْـًٔا ۗ وَسِعَ رَبِّى كُلَّ شَىْءٍ عِلْمًا ۗ أَفَلَا تَتَذَكَّرُونَ","en":"And his people argued with him. He said, \"Do you argue with me concerning Allāh while He has guided me? And I fear not what you associate with Him [and will not be harmed] unless my Lord should will something. My Lord encompasses all things in knowledge; then will you not remember?","tr":"Wahajjahu qawmuhu qala atuhajjoonneefee Allahi waqad hadani wala akhafu matushrikoona bihi illa an yashaa rabbee shay-anwasiAAa rabbee kulla shay-in AAilman afala tatathakkaroon","juz":7,"page":137},{"s":6,"a":81,"key":"6:81","ar":"وَكَيْفَ أَخَافُ مَآ أَشْرَكْتُمْ وَلَا تَخَافُونَ أَنَّكُمْ أَشْرَكْتُم بِٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ عَلَيْكُمْ سُلْطَـٰنًا ۚ فَأَىُّ ٱلْفَرِيقَيْنِ أَحَقُّ بِٱلْأَمْنِ ۖ إِن كُنتُمْ تَعْلَمُونَ","en":"And how should I fear what you associate while you do not fear that you have associated with Allāh that for which He has not sent down to you any authority? So which of the two parties has more right to security, if you should know?\"","tr":"Wakayfa akhafu ma ashraktumwala takhafoona annakum ashraktum billahima lam yunazzil bihi AAalaykum sultanan faayyualfareeqayni ahaqqu bil-amni in kuntum taAAlamoon","juz":7,"page":137},{"s":6,"a":82,"key":"6:82","ar":"ٱلَّذِينَ ءَامَنُوا۟ وَلَمْ يَلْبِسُوٓا۟ إِيمَـٰنَهُم بِظُلْمٍ أُو۟لَـٰٓئِكَ لَهُمُ ٱلْأَمْنُ وَهُم مُّهْتَدُونَ","en":"They who believe and do not mix their belief with injustice1 - those will have security, and they are [rightly] guided.","tr":"Allatheena amanoo walamyalbisoo eemanahum bithulmin ola-ikalahumu al-amnu wahum muhtadoon","juz":7,"page":138},{"s":6,"a":83,"key":"6:83","ar":"وَتِلْكَ حُجَّتُنَآ ءَاتَيْنَـٰهَآ إِبْرَٰهِيمَ عَلَىٰ قَوْمِهِۦ ۚ نَرْفَعُ دَرَجَـٰتٍ مَّن نَّشَآءُ ۗ إِنَّ رَبَّكَ حَكِيمٌ عَلِيمٌ","en":"And that was Our [conclusive] argument which We gave Abraham against his people. We raise by degrees whom We will. Indeed, your Lord is Wise and Knowing.","tr":"Watilka hujjatuna ataynahaibraheema AAala qawmihi narfaAAu darajatinman nashao inna rabbaka hakeemun AAaleem","juz":7,"page":138},{"s":6,"a":84,"key":"6:84","ar":"وَوَهَبْنَا لَهُۥٓ إِسْحَـٰقَ وَيَعْقُوبَ ۚ كُلًّا هَدَيْنَا ۚ وَنُوحًا هَدَيْنَا مِن قَبْلُ ۖ وَمِن ذُرِّيَّتِهِۦ دَاوُۥدَ وَسُلَيْمَـٰنَ وَأَيُّوبَ وَيُوسُفَ وَمُوسَىٰ وَهَـٰرُونَ ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ","en":"And We gave to him [i.e., Abraham] Isaac and Jacob - all [of them] We guided. And Noah, We guided before; and among his descendants, David and Solomon and Job and Joseph and Moses and Aaron. Thus do We reward the doers of good.","tr":"Wawahabna lahu ishaqawayaAAqooba kullan hadayna wanoohan hadaynamin qablu wamin thurriyyatihi dawooda wasulaymanawaayyooba wayoosufa wamoosa waharoona wakathalikanajzee almuhsineen","juz":7,"page":138},{"s":6,"a":85,"key":"6:85","ar":"وَزَكَرِيَّا وَيَحْيَىٰ وَعِيسَىٰ وَإِلْيَاسَ ۖ كُلٌّ مِّنَ ٱلصَّـٰلِحِينَ","en":"And Zechariah and John and Jesus and Elias - and all were of the righteous.","tr":"Wazakariyya wayahyawaAAeesa walyasa kullun mina assaliheen","juz":7,"page":138},{"s":6,"a":86,"key":"6:86","ar":"وَإِسْمَـٰعِيلَ وَٱلْيَسَعَ وَيُونُسَ وَلُوطًا ۚ وَكُلًّا فَضَّلْنَا عَلَى ٱلْعَـٰلَمِينَ","en":"And Ishmael and Elisha and Jonah and Lot - and all [of them] We preferred over the worlds.","tr":"Wa-ismaAAeela walyasaAAawayoonusa walootan wakullan faddalna AAalaalAAalameen","juz":7,"page":138},{"s":6,"a":87,"key":"6:87","ar":"وَمِنْ ءَابَآئِهِمْ وَذُرِّيَّـٰتِهِمْ وَإِخْوَٰنِهِمْ ۖ وَٱجْتَبَيْنَـٰهُمْ وَهَدَيْنَـٰهُمْ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"And [some] among their fathers and their descendants and their brothers - and We chose them and We guided them to a straight path.","tr":"Wamin aba-ihim wathurriyyatihimwa-ikhwanihim wajtabaynahum wahadaynahumila siratin mustaqeem","juz":7,"page":138},{"s":6,"a":88,"key":"6:88","ar":"ذَٰلِكَ هُدَى ٱللَّهِ يَهْدِى بِهِۦ مَن يَشَآءُ مِنْ عِبَادِهِۦ ۚ وَلَوْ أَشْرَكُوا۟ لَحَبِطَ عَنْهُم مَّا كَانُوا۟ يَعْمَلُونَ","en":"That is the guidance of Allāh by which He guides whomever He wills of His servants. But if they had associated others with Allāh, then worthless for them would be whatever they were doing.","tr":"Thalika huda Allahiyahdee bihi man yashao min AAibadihi walaw ashrakoolahabita AAanhum ma kanoo yaAAmaloon","juz":7,"page":138},{"s":6,"a":89,"key":"6:89","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ ءَاتَيْنَـٰهُمُ ٱلْكِتَـٰبَ وَٱلْحُكْمَ وَٱلنُّبُوَّةَ ۚ فَإِن يَكْفُرْ بِهَا هَـٰٓؤُلَآءِ فَقَدْ وَكَّلْنَا بِهَا قَوْمًا لَّيْسُوا۟ بِهَا بِكَـٰفِرِينَ","en":"Those are the ones to whom We gave the Scripture and authority and prophethood. But if they [i.e., the disbelievers] deny it, then We have entrusted it to a people who are not therein disbelievers.","tr":"Ola-ika allatheena ataynahumualkitaba walhukma wannubuwwatafa-in yakfur biha haola-i faqad wakkalnabiha qawman laysoo biha bikafireen","juz":7,"page":138},{"s":6,"a":90,"key":"6:90","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ هَدَى ٱللَّهُ ۖ فَبِهُدَىٰهُمُ ٱقْتَدِهْ ۗ قُل لَّآ أَسْـَٔلُكُمْ عَلَيْهِ أَجْرًا ۖ إِنْ هُوَ إِلَّا ذِكْرَىٰ لِلْعَـٰلَمِينَ","en":"Those are the ones whom Allāh has guided, so from their guidance take an example. Say, \"I ask of you for it [i.e., this message] no payment. It is not but a reminder for the worlds.\"","tr":"Ola-ika allatheena hadaAllahu fabihudahumu iqtadih qul la as-alukumAAalayhi ajran in huwa illa thikra lilAAalameen","juz":7,"page":138},{"s":6,"a":91,"key":"6:91","ar":"وَمَا قَدَرُوا۟ ٱللَّهَ حَقَّ قَدْرِهِۦٓ إِذْ قَالُوا۟ مَآ أَنزَلَ ٱللَّهُ عَلَىٰ بَشَرٍ مِّن شَىْءٍ ۗ قُلْ مَنْ أَنزَلَ ٱلْكِتَـٰبَ ٱلَّذِى جَآءَ بِهِۦ مُوسَىٰ نُورًا وَهُدًى لِّلنَّاسِ ۖ تَجْعَلُونَهُۥ قَرَاطِيسَ تُبْدُونَهَا وَتُخْفُونَ كَثِيرًا ۖ وَعُلِّمْتُم مَّا لَمْ تَعْلَمُوٓا۟ أَنتُمْ وَلَآ ءَابَآؤُكُمْ ۖ قُلِ ٱللَّهُ ۖ ثُمَّ ذَرْهُمْ فِى خَوْضِهِمْ يَلْعَبُونَ","en":"And they did not appraise Allāh with true appraisal1 when they said, \"Allāh did not reveal to a human being anything.\" Say, \"Who revealed the Scripture that Moses brought as light and guidance to the people? You [Jews] make it into pages, disclosing [some of] it and concealing much. And you2 were taught that which you knew not - neither you nor your fathers.\" Say, \"Allāh [revealed it].\" Then leave them in their [empty] discourse, amusing themselves.","tr":"Wama qadaroo Allaha haqqaqadrihi ith qaloo ma anzala AllahuAAala basharin min shay-in qul man anzala alkitabaallathee jaa bihi moosa nooran wahudan linnasitajAAaloonahu qarateesa tubdoonaha watukhfoonakatheeran waAAullimtum ma lam taAAlamoo antum wala abaokumquli Allahu thumma tharhum fee khawdihimyalAAaboon","juz":7,"page":139},{"s":6,"a":92,"key":"6:92","ar":"وَهَـٰذَا كِتَـٰبٌ أَنزَلْنَـٰهُ مُبَارَكٌ مُّصَدِّقُ ٱلَّذِى بَيْنَ يَدَيْهِ وَلِتُنذِرَ أُمَّ ٱلْقُرَىٰ وَمَنْ حَوْلَهَا ۚ وَٱلَّذِينَ يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ يُؤْمِنُونَ بِهِۦ ۖ وَهُمْ عَلَىٰ صَلَاتِهِمْ يُحَافِظُونَ","en":"And this is a Book which We have sent down, blessed and confirming what was before it, that you may warn the Mother of Cities [i.e., Makkah] and those around it.1 Those who believe in the Hereafter believe in it, and they are maintaining their prayers.","tr":"Wahatha kitabun anzalnahumubarakun musaddiqu allathee bayna yadayhiwalitunthira omma alqura waman hawlahawallatheena yu/minoona bil-akhiratiyu/minoona bihi wahum AAala salatihim yuhafithoon","juz":7,"page":139},{"s":6,"a":93,"key":"6:93","ar":"وَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوْ قَالَ أُوحِىَ إِلَىَّ وَلَمْ يُوحَ إِلَيْهِ شَىْءٌ وَمَن قَالَ سَأُنزِلُ مِثْلَ مَآ أَنزَلَ ٱللَّهُ ۗ وَلَوْ تَرَىٰٓ إِذِ ٱلظَّـٰلِمُونَ فِى غَمَرَٰتِ ٱلْمَوْتِ وَٱلْمَلَـٰٓئِكَةُ بَاسِطُوٓا۟ أَيْدِيهِمْ أَخْرِجُوٓا۟ أَنفُسَكُمُ ۖ ٱلْيَوْمَ تُجْزَوْنَ عَذَابَ ٱلْهُونِ بِمَا كُنتُمْ تَقُولُونَ عَلَى ٱللَّهِ غَيْرَ ٱلْحَقِّ وَكُنتُمْ عَنْ ءَايَـٰتِهِۦ تَسْتَكْبِرُونَ","en":"And who is more unjust than one who invents a lie about Allāh or says, \"It has been inspired to me,\" while nothing has been inspired to him, and one who says, \"I will reveal [something] like what Allāh revealed.\" And if you could but see when the wrongdoers are in the overwhelming pangs of death while the angels extend their hands,1 [saying], \"Discharge your souls! Today you will be awarded the punishment of [extreme] humiliation for what you used to say against Allāh other than the truth and [that] you were, toward His verses, being arrogant.\"","tr":"Waman athlamu mimmani iftaraAAala Allahi kathiban aw qala oohiyailayya walam yooha ilayhi shay-on waman qalasaonzilu mithla ma anzala Allahu walaw taraithi aththalimoona fee ghamaratialmawti walmala-ikatu basitooaydeehim akhrijoo anfusakumu alyawma tujzawna AAathabaalhooni bima kuntum taqooloona AAala Allahighayra alhaqqi wakuntum AAan ayatihitastakbiroon","juz":7,"page":139},{"s":6,"a":94,"key":"6:94","ar":"وَلَقَدْ جِئْتُمُونَا فُرَٰدَىٰ كَمَا خَلَقْنَـٰكُمْ أَوَّلَ مَرَّةٍ وَتَرَكْتُم مَّا خَوَّلْنَـٰكُمْ وَرَآءَ ظُهُورِكُمْ ۖ وَمَا نَرَىٰ مَعَكُمْ شُفَعَآءَكُمُ ٱلَّذِينَ زَعَمْتُمْ أَنَّهُمْ فِيكُمْ شُرَكَـٰٓؤُا۟ ۚ لَقَد تَّقَطَّعَ بَيْنَكُمْ وَضَلَّ عَنكُم مَّا كُنتُمْ تَزْعُمُونَ","en":"[It will be said to them], \"And you have certainly come to Us alone [i.e., individually] as We created you the first time, and you have left whatever We bestowed upon you behind you. And We do not see with you your 'intercessors' which you claimed that they were among you associates [of Allāh]. It has [all] been severed between you,1 and lost from you is what you used to claim.\"","tr":"Walaqad ji/tumoona furadakama khalaqnakum awwala marratin wataraktum makhawwalnakum waraa thuhoorikum wamanara maAAakum shufaAAaakumu allatheenazaAAamtum annahum feekum shurakao laqad taqattaAAabaynakum wadalla AAankum ma kuntum tazAAumoon","juz":7,"page":139},{"s":6,"a":95,"key":"6:95","ar":"۞ إِنَّ ٱللَّهَ فَالِقُ ٱلْحَبِّ وَٱلنَّوَىٰ ۖ يُخْرِجُ ٱلْحَىَّ مِنَ ٱلْمَيِّتِ وَمُخْرِجُ ٱلْمَيِّتِ مِنَ ٱلْحَىِّ ۚ ذَٰلِكُمُ ٱللَّهُ ۖ فَأَنَّىٰ تُؤْفَكُونَ","en":"Indeed, Allāh is the cleaver of grain and date seeds.1 He brings the living out of the dead and brings the dead out of the living. That is Allāh; so how are you deluded?","tr":"Inna Allaha faliqu alhabbiwannawa yukhriju alhayya mina almayyitiwamukhriju almayyiti mina alhayyi thalikumu Allahufaanna tu/fakoon","juz":7,"page":140},{"s":6,"a":96,"key":"6:96","ar":"فَالِقُ ٱلْإِصْبَاحِ وَجَعَلَ ٱلَّيْلَ سَكَنًا وَٱلشَّمْسَ وَٱلْقَمَرَ حُسْبَانًا ۚ ذَٰلِكَ تَقْدِيرُ ٱلْعَزِيزِ ٱلْعَلِيمِ","en":"[He is] the cleaver of daybreak and has made the night for rest and the sun and moon for calculation.1 That is the determination of the Exalted in Might, the Knowing.","tr":"Faliqu al-isbahiwajaAAala allayla sakanan washshamsa walqamara husbananthalika taqdeeru alAAazeezi alAAaleem","juz":7,"page":140},{"s":6,"a":97,"key":"6:97","ar":"وَهُوَ ٱلَّذِى جَعَلَ لَكُمُ ٱلنُّجُومَ لِتَهْتَدُوا۟ بِهَا فِى ظُلُمَـٰتِ ٱلْبَرِّ وَٱلْبَحْرِ ۗ قَدْ فَصَّلْنَا ٱلْـَٔايَـٰتِ لِقَوْمٍ يَعْلَمُونَ","en":"And it is He who placed for you the stars that you may be guided by them through the darknesses of the land and sea. We have detailed the signs for a people who know.","tr":"Wahuwa allathee jaAAala lakumu annujoomalitahtadoo biha fee thulumati albarriwalbahri qad fassalna al-ayatiliqawmin yaAAlamoon","juz":7,"page":140},{"s":6,"a":98,"key":"6:98","ar":"وَهُوَ ٱلَّذِىٓ أَنشَأَكُم مِّن نَّفْسٍ وَٰحِدَةٍ فَمُسْتَقَرٌّ وَمُسْتَوْدَعٌ ۗ قَدْ فَصَّلْنَا ٱلْـَٔايَـٰتِ لِقَوْمٍ يَفْقَهُونَ","en":"And it is He who produced you from one soul and [gave you] a place of dwelling and of storage.1 We have detailed the signs for a people who understand.","tr":"Wahuwa allathee anshaakum min nafsinwahidatin famustaqarrun wamustawdaAAun qad fassalnaal-ayati liqawmin yafqahoon","juz":7,"page":140},{"s":6,"a":99,"key":"6:99","ar":"وَهُوَ ٱلَّذِىٓ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً فَأَخْرَجْنَا بِهِۦ نَبَاتَ كُلِّ شَىْءٍ فَأَخْرَجْنَا مِنْهُ خَضِرًا نُّخْرِجُ مِنْهُ حَبًّا مُّتَرَاكِبًا وَمِنَ ٱلنَّخْلِ مِن طَلْعِهَا قِنْوَانٌ دَانِيَةٌ وَجَنَّـٰتٍ مِّنْ أَعْنَابٍ وَٱلزَّيْتُونَ وَٱلرُّمَّانَ مُشْتَبِهًا وَغَيْرَ مُتَشَـٰبِهٍ ۗ ٱنظُرُوٓا۟ إِلَىٰ ثَمَرِهِۦٓ إِذَآ أَثْمَرَ وَيَنْعِهِۦٓ ۚ إِنَّ فِى ذَٰلِكُمْ لَـَٔايَـٰتٍ لِّقَوْمٍ يُؤْمِنُونَ","en":"And it is He who sends down rain from the sky, and We produce thereby the growth of all things. We produce from it greenery from which We produce grains arranged in layers. And from the palm trees - of its emerging fruit are clusters hanging low. And [We produce] gardens of grapevines and olives and pomegranates, similar yet varied. Look at [each of] its fruit when it yields and [at] its ripening. Indeed in that are signs for a people who believe.","tr":"Wahuwa allathee anzala mina assama-imaan faakhrajna bihi nabata kulli shay-infaakhrajna minhu khadiran nukhriju minhu habbanmutarakiban wamina annakhli min talAAihaqinwanun daniyatun wajannatin min aAAnabinwazzaytoona warrummana mushtabihanwaghayra mutashabihin onthuroo ilathamarihi itha athmara wayanAAihi inna fee thalikumlaayatin liqawmin yu/minoon","juz":7,"page":140},{"s":6,"a":100,"key":"6:100","ar":"وَجَعَلُوا۟ لِلَّهِ شُرَكَآءَ ٱلْجِنَّ وَخَلَقَهُمْ ۖ وَخَرَقُوا۟ لَهُۥ بَنِينَ وَبَنَـٰتٍۭ بِغَيْرِ عِلْمٍ ۚ سُبْحَـٰنَهُۥ وَتَعَـٰلَىٰ عَمَّا يَصِفُونَ","en":"But they have attributed to Allāh partners - the jinn, while He has created them - and have fabricated for Him sons and daughters without knowledge. Exalted is He and high above what they describe.","tr":"WajaAAaloo lillahi shurakaaaljinna wakhalaqahum wakharaqoo lahu baneena wabanatinbighayri AAilmin subhanahu wataAAala AAammayasifoon","juz":7,"page":140},{"s":6,"a":101,"key":"6:101","ar":"بَدِيعُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ أَنَّىٰ يَكُونُ لَهُۥ وَلَدٌ وَلَمْ تَكُن لَّهُۥ صَـٰحِبَةٌ ۖ وَخَلَقَ كُلَّ شَىْءٍ ۖ وَهُوَ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"[He is] Originator of the heavens and the earth. How could He have a son when He does not have a companion [i.e., wife] and He created all things? And He is, of all things, Knowing.","tr":"BadeeAAu assamawatiwal-ardi anna yakoonu lahu waladun walamtakun lahu sahibatun wakhalaqa kulla shay-in wahuwabikulli shay-in AAaleem","juz":7,"page":140},{"s":6,"a":102,"key":"6:102","ar":"ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ ۖ لَآ إِلَـٰهَ إِلَّا هُوَ ۖ خَـٰلِقُ كُلِّ شَىْءٍ فَٱعْبُدُوهُ ۚ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ وَكِيلٌ","en":"That is Allāh, your Lord; there is no deity except Him, the Creator of all things, so worship Him. And He is Disposer of all things.","tr":"Thalikumu Allahu rabbukum lailaha illa huwa khaliqu kulli shay-in faAAbudoohuwahuwa AAala kulli shay-in wakeel","juz":7,"page":141},{"s":6,"a":103,"key":"6:103","ar":"لَّا تُدْرِكُهُ ٱلْأَبْصَـٰرُ وَهُوَ يُدْرِكُ ٱلْأَبْصَـٰرَ ۖ وَهُوَ ٱللَّطِيفُ ٱلْخَبِيرُ","en":"Vision perceives Him not,1 but He perceives [all] vision; and He is the Subtle,2 the Aware.3","tr":"La tudrikuhu al-absaru wahuwayudriku al-absara wahuwa allateefu alkhabeer","juz":7,"page":141},{"s":6,"a":104,"key":"6:104","ar":"قَدْ جَآءَكُم بَصَآئِرُ مِن رَّبِّكُمْ ۖ فَمَنْ أَبْصَرَ فَلِنَفْسِهِۦ ۖ وَمَنْ عَمِىَ فَعَلَيْهَا ۚ وَمَآ أَنَا۠ عَلَيْكُم بِحَفِيظٍ","en":"There has come to you enlightenment from your Lord. So whoever will see does so for [the benefit of] his soul, and whoever is blind [does harm] against it. And [say], \"I am not a guardian over you.\"1","tr":"Qad jaakum basa-iru minrabbikum faman absara falinafsihi waman AAamiya faAAalayhawama ana AAalaykum bihafeeth","juz":7,"page":141},{"s":6,"a":105,"key":"6:105","ar":"وَكَذَٰلِكَ نُصَرِّفُ ٱلْـَٔايَـٰتِ وَلِيَقُولُوا۟ دَرَسْتَ وَلِنُبَيِّنَهُۥ لِقَوْمٍ يَعْلَمُونَ","en":"And thus do We diversify the verses so they [i.e., the disbelievers] will say, \"You have studied,\"1 and so We may make it [i.e., the Qur’ān] clear for a people who know.","tr":"Wakathalika nusarrifu al-ayatiwaliyaqooloo darasta walinubayyinahu liqawmin yaAAlamoon","juz":7,"page":141},{"s":6,"a":106,"key":"6:106","ar":"ٱتَّبِعْ مَآ أُوحِىَ إِلَيْكَ مِن رَّبِّكَ ۖ لَآ إِلَـٰهَ إِلَّا هُوَ ۖ وَأَعْرِضْ عَنِ ٱلْمُشْرِكِينَ","en":"Follow, [O Muḥammad], what has been revealed to you from your Lord - there is no deity except Him - and turn away from those who associate others with Allāh.","tr":"IttabiAA ma oohiya ilayka minrabbika la ilaha illa huwa waaAAridAAani almushrikeen","juz":7,"page":141},{"s":6,"a":107,"key":"6:107","ar":"وَلَوْ شَآءَ ٱللَّهُ مَآ أَشْرَكُوا۟ ۗ وَمَا جَعَلْنَـٰكَ عَلَيْهِمْ حَفِيظًا ۖ وَمَآ أَنتَ عَلَيْهِم بِوَكِيلٍ","en":"But if Allāh had willed, they would not have associated. And We have not appointed you over them as a guardian, nor are you a manager over them.1","tr":"Walaw shaa Allahu maashrakoo wama jaAAalnaka AAalayhim hafeethanwama anta AAalayhim biwakeel","juz":7,"page":141},{"s":6,"a":108,"key":"6:108","ar":"وَلَا تَسُبُّوا۟ ٱلَّذِينَ يَدْعُونَ مِن دُونِ ٱللَّهِ فَيَسُبُّوا۟ ٱللَّهَ عَدْوًۢا بِغَيْرِ عِلْمٍ ۗ كَذَٰلِكَ زَيَّنَّا لِكُلِّ أُمَّةٍ عَمَلَهُمْ ثُمَّ إِلَىٰ رَبِّهِم مَّرْجِعُهُمْ فَيُنَبِّئُهُم بِمَا كَانُوا۟ يَعْمَلُونَ","en":"And do not insult those they invoke other than Allāh, lest they insult Allāh in enmity without knowledge. Thus We have made pleasing to every community their deeds. Then to their Lord is their return, and He will inform them about what they used to do.","tr":"Wala tasubboo allatheenayadAAoona min dooni Allahi fayasubboo AllahaAAadwan bighayri AAilmin kathalika zayyanna likulliommatin AAamalahum thumma ila rabbihim marjiAAuhumfayunabbi-ohum bima kanoo yaAAmaloon","juz":7,"page":141},{"s":6,"a":109,"key":"6:109","ar":"وَأَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَـٰنِهِمْ لَئِن جَآءَتْهُمْ ءَايَةٌ لَّيُؤْمِنُنَّ بِهَا ۚ قُلْ إِنَّمَا ٱلْـَٔايَـٰتُ عِندَ ٱللَّهِ ۖ وَمَا يُشْعِرُكُمْ أَنَّهَآ إِذَا جَآءَتْ لَا يُؤْمِنُونَ","en":"And they swear by Allāh their strongest oaths that if a sign came to them, they would surely believe in it. Say, \"The signs are only with [i.e., from] Allāh.\" And what will make you perceive that even if it [i.e., a sign] came, they would not believe.","tr":"Waaqsamoo billahi jahda aymanihimla-in jaat-hum ayatun layu/minunna biha qulinnama al-ayatu AAinda Allahi wamayushAAirukum annaha itha jaat layu/minoon","juz":7,"page":141},{"s":6,"a":110,"key":"6:110","ar":"وَنُقَلِّبُ أَفْـِٔدَتَهُمْ وَأَبْصَـٰرَهُمْ كَمَا لَمْ يُؤْمِنُوا۟ بِهِۦٓ أَوَّلَ مَرَّةٍ وَنَذَرُهُمْ فِى طُغْيَـٰنِهِمْ يَعْمَهُونَ","en":"And We will turn away their hearts and their eyes just as they refused to believe in it [i.e., the revelation] the first time. And We will leave them in their transgression, wandering blindly.","tr":"Wanuqallibu af-idatahum waabsarahumkama lam yu/minoo bihi awwala marratin wanatharuhumfee tughyanihim yaAAmahoon","juz":7,"page":141},{"s":6,"a":111,"key":"6:111","ar":"۞ وَلَوْ أَنَّنَا نَزَّلْنَآ إِلَيْهِمُ ٱلْمَلَـٰٓئِكَةَ وَكَلَّمَهُمُ ٱلْمَوْتَىٰ وَحَشَرْنَا عَلَيْهِمْ كُلَّ شَىْءٍ قُبُلًا مَّا كَانُوا۟ لِيُؤْمِنُوٓا۟ إِلَّآ أَن يَشَآءَ ٱللَّهُ وَلَـٰكِنَّ أَكْثَرَهُمْ يَجْهَلُونَ","en":"And even if We had sent down to them the angels [with the message] and the dead spoke to them [of it] and We gathered together every [created] thing in front of them, they would not believe unless Allāh should will. But most of them, [of that], are ignorant.","tr":"Walaw annana nazzalnailayhimu almala-ikata wakallamahumu almawta wahasharnaAAalayhim kulla shay-in qubulan ma kanoo liyu/minooilla an yashaa Allahu walakinnaaktharahum yajhaloon","juz":8,"page":142},{"s":6,"a":112,"key":"6:112","ar":"وَكَذَٰلِكَ جَعَلْنَا لِكُلِّ نَبِىٍّ عَدُوًّا شَيَـٰطِينَ ٱلْإِنسِ وَٱلْجِنِّ يُوحِى بَعْضُهُمْ إِلَىٰ بَعْضٍ زُخْرُفَ ٱلْقَوْلِ غُرُورًا ۚ وَلَوْ شَآءَ رَبُّكَ مَا فَعَلُوهُ ۖ فَذَرْهُمْ وَمَا يَفْتَرُونَ","en":"And thus We have made for every prophet an enemy - devils from mankind and jinn, inspiring to one another decorative speech in delusion. But if your Lord had willed, they would not have done it, so leave them and that which they invent.","tr":"Wakathalika jaAAalna likullinabiyyin AAaduwwan shayateena al-insi waljinni yooheebaAAduhum ila baAAdin zukhrufa alqawlighurooran walaw shaa rabbuka ma faAAaloohu fatharhumwama yaftaroon","juz":8,"page":142},{"s":6,"a":113,"key":"6:113","ar":"وَلِتَصْغَىٰٓ إِلَيْهِ أَفْـِٔدَةُ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ وَلِيَرْضَوْهُ وَلِيَقْتَرِفُوا۟ مَا هُم مُّقْتَرِفُونَ","en":"And [it is] so the hearts of those who disbelieve in the Hereafter will incline toward it [i.e., deceptive speech] and that they will be satisfied with it and that they will commit that which they are committing.","tr":"Walitasgha ilayhi af-idatuallatheena la yu/minoona bil-akhiratiwaliyardawhu waliyaqtarifoo ma hum muqtarifoon","juz":8,"page":142},{"s":6,"a":114,"key":"6:114","ar":"أَفَغَيْرَ ٱللَّهِ أَبْتَغِى حَكَمًا وَهُوَ ٱلَّذِىٓ أَنزَلَ إِلَيْكُمُ ٱلْكِتَـٰبَ مُفَصَّلًا ۚ وَٱلَّذِينَ ءَاتَيْنَـٰهُمُ ٱلْكِتَـٰبَ يَعْلَمُونَ أَنَّهُۥ مُنَزَّلٌ مِّن رَّبِّكَ بِٱلْحَقِّ ۖ فَلَا تَكُونَنَّ مِنَ ٱلْمُمْتَرِينَ","en":"[Say], \"Then is it other than Allāh I should seek as judge while it is He who has revealed to you the Book [i.e., the Qur’ān] explained in detail?\" And those to whom We [previously] gave the Scripture know that it is sent down from your Lord in truth, so never be among the doubters.","tr":"Afaghayra Allahi abtaghee hakamanwahuwa allathee anzala ilaykumu alkitaba mufassalanwallatheena ataynahumu alkitabayaAAlamoona annahu munazzalun min rabbika bilhaqqifala takoonanna mina almumtareen","juz":8,"page":142},{"s":6,"a":115,"key":"6:115","ar":"وَتَمَّتْ كَلِمَتُ رَبِّكَ صِدْقًا وَعَدْلًا ۚ لَّا مُبَدِّلَ لِكَلِمَـٰتِهِۦ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"And the word of your Lord has been fulfilled in truth and in justice. None can alter His words, and He is the Hearing, the Knowing.","tr":"Watammat kalimatu rabbika sidqanwaAAadlan la mubaddila likalimatihi wahuwa assameeAAualAAaleem","juz":8,"page":142},{"s":6,"a":116,"key":"6:116","ar":"وَإِن تُطِعْ أَكْثَرَ مَن فِى ٱلْأَرْضِ يُضِلُّوكَ عَن سَبِيلِ ٱللَّهِ ۚ إِن يَتَّبِعُونَ إِلَّا ٱلظَّنَّ وَإِنْ هُمْ إِلَّا يَخْرُصُونَ","en":"And if you obey most of those upon the earth, they will mislead you from the way of Allāh. They follow not except assumption, and they are not but misjudging.1","tr":"Wa-in tutiAA akthara man fee al-ardiyudillooka AAan sabeeli Allahi in yattabiAAoona illaaththanna wa-in hum illa yakhrusoon","juz":8,"page":142},{"s":6,"a":117,"key":"6:117","ar":"إِنَّ رَبَّكَ هُوَ أَعْلَمُ مَن يَضِلُّ عَن سَبِيلِهِۦ ۖ وَهُوَ أَعْلَمُ بِٱلْمُهْتَدِينَ","en":"Indeed, your Lord is most knowing of who strays from His way, and He is most knowing of the [rightly] guided.","tr":"Inna rabbaka huwa aAAlamu man yadilluAAan sabeelihi wahuwa aAAlamu bilmuhtadeen","juz":8,"page":142},{"s":6,"a":118,"key":"6:118","ar":"فَكُلُوا۟ مِمَّا ذُكِرَ ٱسْمُ ٱللَّهِ عَلَيْهِ إِن كُنتُم بِـَٔايَـٰتِهِۦ مُؤْمِنِينَ","en":"So eat of that [meat] upon which the name of Allāh has been mentioned,1 if you are believers in His verses [i.e., revealed law].","tr":"Fakuloo mimma thukira ismuAllahi AAalayhi in kuntum bi-ayatihimu/mineen","juz":8,"page":142},{"s":6,"a":119,"key":"6:119","ar":"وَمَا لَكُمْ أَلَّا تَأْكُلُوا۟ مِمَّا ذُكِرَ ٱسْمُ ٱللَّهِ عَلَيْهِ وَقَدْ فَصَّلَ لَكُم مَّا حَرَّمَ عَلَيْكُمْ إِلَّا مَا ٱضْطُرِرْتُمْ إِلَيْهِ ۗ وَإِنَّ كَثِيرًا لَّيُضِلُّونَ بِأَهْوَآئِهِم بِغَيْرِ عِلْمٍ ۗ إِنَّ رَبَّكَ هُوَ أَعْلَمُ بِٱلْمُعْتَدِينَ","en":"And why should you not eat of that upon which the name of Allāh has been mentioned while He has explained in detail to you what He has forbidden you, excepting that to which you are compelled.1 And indeed do many lead [others] astray through their [own] inclinations without knowledge. Indeed, your Lord - He is most knowing of the transgressors.","tr":"Wama lakum alla ta/kuloo mimmathukira ismu Allahi AAalayhi waqad fassalalakum ma harrama AAalaykum illa ma idturirtumilayhi wa-inna katheeran layudilloona bi-ahwa-ihimbighayri AAilmin inna rabbaka huwa aAAlamu bilmuAAtadeen","juz":8,"page":143},{"s":6,"a":120,"key":"6:120","ar":"وَذَرُوا۟ ظَـٰهِرَ ٱلْإِثْمِ وَبَاطِنَهُۥٓ ۚ إِنَّ ٱلَّذِينَ يَكْسِبُونَ ٱلْإِثْمَ سَيُجْزَوْنَ بِمَا كَانُوا۟ يَقْتَرِفُونَ","en":"And leave [i.e., desist from] what is apparent of sin and what is concealed thereof. Indeed, those who earn [blame for] sin will be recompensed for that which they used to commit.","tr":"Watharoo thahiraal-ithmi wabatinahu inna allatheena yaksiboonaal-ithma sayujzawna bima kanoo yaqtarifoon","juz":8,"page":143},{"s":6,"a":121,"key":"6:121","ar":"وَلَا تَأْكُلُوا۟ مِمَّا لَمْ يُذْكَرِ ٱسْمُ ٱللَّهِ عَلَيْهِ وَإِنَّهُۥ لَفِسْقٌ ۗ وَإِنَّ ٱلشَّيَـٰطِينَ لَيُوحُونَ إِلَىٰٓ أَوْلِيَآئِهِمْ لِيُجَـٰدِلُوكُمْ ۖ وَإِنْ أَطَعْتُمُوهُمْ إِنَّكُمْ لَمُشْرِكُونَ","en":"And do not eat of that upon which the name of Allāh has not been mentioned, for indeed, it is grave disobedience. And indeed do the devils inspire their allies [among men] to dispute with you. And if you were to obey them, indeed, you would be associators [of others with Him].1","tr":"Wala ta/kuloo mimma lam yuthkariismu Allahi AAalayhi wa-innahu lafisqun wa-inna ashshayateenalayoohoona ila awliya-ihim liyujadilookumwa-in ataAAtumoohum innakum lamushrikoon","juz":8,"page":143},{"s":6,"a":122,"key":"6:122","ar":"أَوَمَن كَانَ مَيْتًا فَأَحْيَيْنَـٰهُ وَجَعَلْنَا لَهُۥ نُورًا يَمْشِى بِهِۦ فِى ٱلنَّاسِ كَمَن مَّثَلُهُۥ فِى ٱلظُّلُمَـٰتِ لَيْسَ بِخَارِجٍ مِّنْهَا ۚ كَذَٰلِكَ زُيِّنَ لِلْكَـٰفِرِينَ مَا كَانُوا۟ يَعْمَلُونَ","en":"And is one who was dead and We gave him life and made for him light by which to walk among the people like one who is in darkness, never to emerge therefrom? Thus it has been made pleasing to the disbelievers that which they were doing.","tr":"Awa man kana maytan faahyaynahuwajaAAalna lahu nooran yamshee bihi fee annasikaman mathaluhu fee aththulumatilaysa bikharijin minha kathalika zuyyinalilkafireena ma kanoo yaAAmaloon","juz":8,"page":143},{"s":6,"a":123,"key":"6:123","ar":"وَكَذَٰلِكَ جَعَلْنَا فِى كُلِّ قَرْيَةٍ أَكَـٰبِرَ مُجْرِمِيهَا لِيَمْكُرُوا۟ فِيهَا ۖ وَمَا يَمْكُرُونَ إِلَّا بِأَنفُسِهِمْ وَمَا يَشْعُرُونَ","en":"And thus We have placed within every city the greatest of its criminals to conspire therein. But they conspire not except against themselves, and they perceive [it] not.","tr":"Wakathalika jaAAalna feekulli qaryatin akabira mujrimeeha liyamkuroo feehawama yamkuroona illa bi-anfusihim wamayashAAuroon","juz":8,"page":143},{"s":6,"a":124,"key":"6:124","ar":"وَإِذَا جَآءَتْهُمْ ءَايَةٌ قَالُوا۟ لَن نُّؤْمِنَ حَتَّىٰ نُؤْتَىٰ مِثْلَ مَآ أُوتِىَ رُسُلُ ٱللَّهِ ۘ ٱللَّهُ أَعْلَمُ حَيْثُ يَجْعَلُ رِسَالَتَهُۥ ۗ سَيُصِيبُ ٱلَّذِينَ أَجْرَمُوا۟ صَغَارٌ عِندَ ٱللَّهِ وَعَذَابٌ شَدِيدٌۢ بِمَا كَانُوا۟ يَمْكُرُونَ","en":"And when a sign comes to them, they say, \"Never will we believe until we are given like that which was given to the messengers of Allāh.\" Allāh is most knowing of where [i.e., with whom] He places His message. There will afflict those who committed crimes debasement before Allāh and severe punishment for what they used to conspire.","tr":"Wa-itha jaat-hum ayatunqaloo lan nu/mina hatta nu/ta mithlama ootiya rusulu Allahi Allahu aAAlamu haythuyajAAalu risalatahu sayuseebu allatheenaajramoo sagharun AAinda Allahi waAAathabunshadeedun bima kanoo yamkuroon","juz":8,"page":143},{"s":6,"a":125,"key":"6:125","ar":"فَمَن يُرِدِ ٱللَّهُ أَن يَهْدِيَهُۥ يَشْرَحْ صَدْرَهُۥ لِلْإِسْلَـٰمِ ۖ وَمَن يُرِدْ أَن يُضِلَّهُۥ يَجْعَلْ صَدْرَهُۥ ضَيِّقًا حَرَجًا كَأَنَّمَا يَصَّعَّدُ فِى ٱلسَّمَآءِ ۚ كَذَٰلِكَ يَجْعَلُ ٱللَّهُ ٱلرِّجْسَ عَلَى ٱلَّذِينَ لَا يُؤْمِنُونَ","en":"So whoever Allāh wants to guide - He expands his breast to [contain] Islām; and whoever He wants to send astray1 - He makes his breast tight and constricted as though he were climbing into the sky. Thus does Allāh place defilement upon those who do not believe.","tr":"Faman yuridi Allahu an yahdiyahuyashrah sadrahu lil-islami waman yurid an yudillahuyajAAal sadrahu dayyiqan harajan kaannamayassaAAAAadu fee assama-i kathalikayajAAalu Allahu arrijsa AAala allatheenala yu/minoon","juz":8,"page":144},{"s":6,"a":126,"key":"6:126","ar":"وَهَـٰذَا صِرَٰطُ رَبِّكَ مُسْتَقِيمًا ۗ قَدْ فَصَّلْنَا ٱلْـَٔايَـٰتِ لِقَوْمٍ يَذَّكَّرُونَ","en":"And this is the path of your Lord, [leading] straight. We have detailed the verses for a people who remember.","tr":"Wahatha siratu rabbikamustaqeeman qad fassalna al-ayatiliqawmin yaththakkaroon","juz":8,"page":144},{"s":6,"a":127,"key":"6:127","ar":"۞ لَهُمْ دَارُ ٱلسَّلَـٰمِ عِندَ رَبِّهِمْ ۖ وَهُوَ وَلِيُّهُم بِمَا كَانُوا۟ يَعْمَلُونَ","en":"For them will be the Home of Peace [i.e., Paradise] with their Lord. And He will be their protecting friend because of what they used to do.","tr":"Lahum daru assalamiAAinda rabbihim wahuwa waliyyuhum bima kanooyaAAmaloon","juz":8,"page":144},{"s":6,"a":128,"key":"6:128","ar":"وَيَوْمَ يَحْشُرُهُمْ جَمِيعًا يَـٰمَعْشَرَ ٱلْجِنِّ قَدِ ٱسْتَكْثَرْتُم مِّنَ ٱلْإِنسِ ۖ وَقَالَ أَوْلِيَآؤُهُم مِّنَ ٱلْإِنسِ رَبَّنَا ٱسْتَمْتَعَ بَعْضُنَا بِبَعْضٍ وَبَلَغْنَآ أَجَلَنَا ٱلَّذِىٓ أَجَّلْتَ لَنَا ۚ قَالَ ٱلنَّارُ مَثْوَىٰكُمْ خَـٰلِدِينَ فِيهَآ إِلَّا مَا شَآءَ ٱللَّهُ ۗ إِنَّ رَبَّكَ حَكِيمٌ عَلِيمٌ","en":"And [mention, O Muḥammad], the Day when He will gather them together [and say], \"O company of jinn, you have [misled] many of mankind.\" And their allies among mankind will say, \"Our Lord, some of us made use of others, and we have [now] reached our term which You appointed for us.\" He will say, \"The Fire is your residence, wherein you will abide eternally, except for what Allāh wills. Indeed, your Lord is Wise and Knowing.\"","tr":"Wayawma yahshuruhum jameeAAan yamaAAshara aljinni qadi istakthartum mina al-insi waqalaawliyaohum mina al-insi rabbana istamtaAAa baAAdunabibaAAdin wabalaghna ajalana allatheeajjalta lana qala annaru mathwakumkhalideena feeha illa ma shaaAllahu inna rabbaka hakeemun AAaleem","juz":8,"page":144},{"s":6,"a":129,"key":"6:129","ar":"وَكَذَٰلِكَ نُوَلِّى بَعْضَ ٱلظَّـٰلِمِينَ بَعْضًۢا بِمَا كَانُوا۟ يَكْسِبُونَ","en":"And thus will We make some of the wrongdoers allies of others for what they used to earn.1","tr":"Wakathalika nuwallee baAAda aththalimeenabaAAdan bima kanoo yaksiboon","juz":8,"page":144},{"s":6,"a":130,"key":"6:130","ar":"يَـٰمَعْشَرَ ٱلْجِنِّ وَٱلْإِنسِ أَلَمْ يَأْتِكُمْ رُسُلٌ مِّنكُمْ يَقُصُّونَ عَلَيْكُمْ ءَايَـٰتِى وَيُنذِرُونَكُمْ لِقَآءَ يَوْمِكُمْ هَـٰذَا ۚ قَالُوا۟ شَهِدْنَا عَلَىٰٓ أَنفُسِنَا ۖ وَغَرَّتْهُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا وَشَهِدُوا۟ عَلَىٰٓ أَنفُسِهِمْ أَنَّهُمْ كَانُوا۟ كَـٰفِرِينَ","en":"\"O company of jinn and mankind,1 did there not come to you messengers from among you, relating to you My verses and warning you of the meeting of this Day of yours?\" They will say, \"We bear witness against ourselves\"; and the worldly life had deluded them, and they will bear witness against themselves that they were disbelievers.","tr":"Ya maAAshara aljinni wal-insialam ya/tikum rusulun minkum yaqussoona AAalaykum ayateewayunthiroonakum liqaa yawmikum hatha qalooshahidna AAala anfusina wagharrat-humu alhayatuaddunya washahidoo AAala anfusihim annahumkanoo kafireen","juz":8,"page":144},{"s":6,"a":131,"key":"6:131","ar":"ذَٰلِكَ أَن لَّمْ يَكُن رَّبُّكَ مُهْلِكَ ٱلْقُرَىٰ بِظُلْمٍ وَأَهْلُهَا غَـٰفِلُونَ","en":"That is because your Lord would not destroy the cities for wrongdoing1 while their people were unaware.","tr":"Thalika an lam yakun rabbuka muhlikaalqura bithulmin waahluha ghafiloon","juz":8,"page":144},{"s":6,"a":132,"key":"6:132","ar":"وَلِكُلٍّ دَرَجَـٰتٌ مِّمَّا عَمِلُوا۟ ۚ وَمَا رَبُّكَ بِغَـٰفِلٍ عَمَّا يَعْمَلُونَ","en":"And for all are degrees [i.e., positions resulting] from what they have done. And your Lord is not unaware of what they do.","tr":"Walikullin darajatun mimmaAAamiloo wama rabbuka bighafilin AAammayaAAmaloon","juz":8,"page":145},{"s":6,"a":133,"key":"6:133","ar":"وَرَبُّكَ ٱلْغَنِىُّ ذُو ٱلرَّحْمَةِ ۚ إِن يَشَأْ يُذْهِبْكُمْ وَيَسْتَخْلِفْ مِنۢ بَعْدِكُم مَّا يَشَآءُ كَمَآ أَنشَأَكُم مِّن ذُرِّيَّةِ قَوْمٍ ءَاخَرِينَ","en":"And your Lord is the Free of need, the possessor of mercy. If He wills, He can do away with you and give succession after you to whomever He wills, just as He produced you from the descendants of another people.","tr":"Warabbuka alghaniyyu thoo arrahmatiin yasha/ yuthhibkum wayastakhlif min baAAdikum mayashao kama anshaakum min thurriyyati qawminakhareen","juz":8,"page":145},{"s":6,"a":134,"key":"6:134","ar":"إِنَّ مَا تُوعَدُونَ لَـَٔاتٍ ۖ وَمَآ أَنتُم بِمُعْجِزِينَ","en":"Indeed, what you are promised is coming, and you will not cause failure [to Allāh].1","tr":"Inna ma tooAAadoona laatinwama antum bimuAAjizeen","juz":8,"page":145},{"s":6,"a":135,"key":"6:135","ar":"قُلْ يَـٰقَوْمِ ٱعْمَلُوا۟ عَلَىٰ مَكَانَتِكُمْ إِنِّى عَامِلٌ ۖ فَسَوْفَ تَعْلَمُونَ مَن تَكُونُ لَهُۥ عَـٰقِبَةُ ٱلدَّارِ ۗ إِنَّهُۥ لَا يُفْلِحُ ٱلظَّـٰلِمُونَ","en":"Say, \"O my people, work according to your position; [for] indeed, I am working. And you are going to know who will have succession in the home.1 Indeed, the wrongdoers will not succeed.\"","tr":"Qul ya qawmi iAAmaloo AAalamakanatikum innee AAamilun fasawfa taAAlamoona mantakoonu lahu AAaqibatu addari innahu layuflihu aththalimoon","juz":8,"page":145},{"s":6,"a":136,"key":"6:136","ar":"وَجَعَلُوا۟ لِلَّهِ مِمَّا ذَرَأَ مِنَ ٱلْحَرْثِ وَٱلْأَنْعَـٰمِ نَصِيبًا فَقَالُوا۟ هَـٰذَا لِلَّهِ بِزَعْمِهِمْ وَهَـٰذَا لِشُرَكَآئِنَا ۖ فَمَا كَانَ لِشُرَكَآئِهِمْ فَلَا يَصِلُ إِلَى ٱللَّهِ ۖ وَمَا كَانَ لِلَّهِ فَهُوَ يَصِلُ إِلَىٰ شُرَكَآئِهِمْ ۗ سَآءَ مَا يَحْكُمُونَ","en":"And they [i.e., the polytheists] assign to Allāh from that which He created of crops and livestock a share and say, \"This is for Allāh,\" by their claim, \"and this is for our 'partners' [associated with Him].\" But what is for their \"partners\" does not reach Allāh, while what is for Allāh - this reaches their \"partners.\" Evil is that which they rule.","tr":"WajaAAaloo lillahi mimma tharaamina alharthi wal-anAAami naseebanfaqaloo hatha lillahi bizaAAmihim wahathalishuraka-ina fama kana lishuraka-ihimfala yasilu ila Allahi wama kanalillahi fahuwa yasilu ila shuraka-ihimsaa ma yahkumoon","juz":8,"page":145},{"s":6,"a":137,"key":"6:137","ar":"وَكَذَٰلِكَ زَيَّنَ لِكَثِيرٍ مِّنَ ٱلْمُشْرِكِينَ قَتْلَ أَوْلَـٰدِهِمْ شُرَكَآؤُهُمْ لِيُرْدُوهُمْ وَلِيَلْبِسُوا۟ عَلَيْهِمْ دِينَهُمْ ۖ وَلَوْ شَآءَ ٱللَّهُ مَا فَعَلُوهُ ۖ فَذَرْهُمْ وَمَا يَفْتَرُونَ","en":"And likewise, to many of the polytheists their partners1 have made [to seem] pleasing the killing of their children in order to bring about their destruction and to cover them with confusion in their religion. And if Allāh had willed, they would not have done so. So leave them and that which they invent.","tr":"Wakathalika zayyana likatheerin minaalmushrikeena qatla awladihim shurakaohumliyurdoohum waliyalbisoo AAalayhim deenahum walaw shaa Allahuma faAAaloohu fatharhum wama yaftaroon","juz":8,"page":145},{"s":6,"a":138,"key":"6:138","ar":"وَقَالُوا۟ هَـٰذِهِۦٓ أَنْعَـٰمٌ وَحَرْثٌ حِجْرٌ لَّا يَطْعَمُهَآ إِلَّا مَن نَّشَآءُ بِزَعْمِهِمْ وَأَنْعَـٰمٌ حُرِّمَتْ ظُهُورُهَا وَأَنْعَـٰمٌ لَّا يَذْكُرُونَ ٱسْمَ ٱللَّهِ عَلَيْهَا ٱفْتِرَآءً عَلَيْهِ ۚ سَيَجْزِيهِم بِمَا كَانُوا۟ يَفْتَرُونَ","en":"And they say, \"These animals1 and crops are forbidden; no one may eat from them except whom we will,\" by their claim. And there are those [camels] whose backs are forbidden [by them]2 and those upon which the name of Allāh is not mentioned3 - [all of this] an invention of untruth about Him.4 He will punish them for what they were inventing.","tr":"Waqaloo hathihi anAAamunwaharthun hijrun la yatAAamuhailla man nashao bizaAAmihim waanAAamun hurrimatthuhooruha waanAAamun la yathkuroonaisma Allahi AAalayha iftiraan AAalayhisayajzeehim bima kanoo yaftaroon","juz":8,"page":146},{"s":6,"a":139,"key":"6:139","ar":"وَقَالُوا۟ مَا فِى بُطُونِ هَـٰذِهِ ٱلْأَنْعَـٰمِ خَالِصَةٌ لِّذُكُورِنَا وَمُحَرَّمٌ عَلَىٰٓ أَزْوَٰجِنَا ۖ وَإِن يَكُن مَّيْتَةً فَهُمْ فِيهِ شُرَكَآءُ ۚ سَيَجْزِيهِمْ وَصْفَهُمْ ۚ إِنَّهُۥ حَكِيمٌ عَلِيمٌ","en":"And they say, \"What is in the bellies of these animals1 is exclusively for our males and forbidden to our females. But if it is [born] dead, then all of them have shares therein.\" He will punish them for their description.2 Indeed, He is Wise and Knowing.","tr":"Waqaloo ma fee butoonihathihi al-anAAami khalisatun lithukoorinawamuharramun AAala azwajina wa-inyakun maytatan fahum feehi shurakao sayajzeehim wasfahuminnahu hakeemun AAaleem","juz":8,"page":146},{"s":6,"a":140,"key":"6:140","ar":"قَدْ خَسِرَ ٱلَّذِينَ قَتَلُوٓا۟ أَوْلَـٰدَهُمْ سَفَهًۢا بِغَيْرِ عِلْمٍ وَحَرَّمُوا۟ مَا رَزَقَهُمُ ٱللَّهُ ٱفْتِرَآءً عَلَى ٱللَّهِ ۚ قَدْ ضَلُّوا۟ وَمَا كَانُوا۟ مُهْتَدِينَ","en":"They will have lost who killed their children in foolishness without knowledge and prohibited what Allāh had provided for them, inventing untruth about Allāh. They have gone astray and were not [rightly] guided.","tr":"Qad khasira allatheena qataloo awladahumsafahan bighayri AAilmin waharramoo ma razaqahumuAllahu iftiraan AAala Allahi qad dalloowama kanoo muhtadeen","juz":8,"page":146},{"s":6,"a":141,"key":"6:141","ar":"۞ وَهُوَ ٱلَّذِىٓ أَنشَأَ جَنَّـٰتٍ مَّعْرُوشَـٰتٍ وَغَيْرَ مَعْرُوشَـٰتٍ وَٱلنَّخْلَ وَٱلزَّرْعَ مُخْتَلِفًا أُكُلُهُۥ وَٱلزَّيْتُونَ وَٱلرُّمَّانَ مُتَشَـٰبِهًا وَغَيْرَ مُتَشَـٰبِهٍ ۚ كُلُوا۟ مِن ثَمَرِهِۦٓ إِذَآ أَثْمَرَ وَءَاتُوا۟ حَقَّهُۥ يَوْمَ حَصَادِهِۦ ۖ وَلَا تُسْرِفُوٓا۟ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُسْرِفِينَ","en":"And He it is who causes gardens to grow, [both] trellised and untrellised, and palm trees and crops of different [kinds of] food and olives and pomegranates, similar and dissimilar. Eat of [each of] its fruit when it yields and give its due [zakāh] on the day of its harvest. And be not excessive.1 Indeed, He does not like those who commit excess.","tr":"Wahuwa allathee anshaa jannatinmaAArooshatin waghayra maAArooshatin wannakhlawazzarAAa mukhtalifan okuluhu wazzaytoona warrummanamutashabihan waghayra mutashabihin kuloo minthamarihi itha athmara waatoo haqqahu yawma hasadihiwala tusrifoo innahu la yuhibbu almusrifeen","juz":8,"page":146},{"s":6,"a":142,"key":"6:142","ar":"وَمِنَ ٱلْأَنْعَـٰمِ حَمُولَةً وَفَرْشًا ۚ كُلُوا۟ مِمَّا رَزَقَكُمُ ٱللَّهُ وَلَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَـٰنِ ۚ إِنَّهُۥ لَكُمْ عَدُوٌّ مُّبِينٌ","en":"And of the grazing livestock are carriers [of burdens] and those [too] small. Eat of what Allāh has provided for you and do not follow the footsteps of Satan.1 Indeed, he is to you a clear enemy.","tr":"Wamina al-anAAami hamoolatanwafarshan kuloo mimma razaqakumu Allahu walatattabiAAoo khutuwati ashshaytaniinnahu lakum AAaduwwun mubeen","juz":8,"page":146},{"s":6,"a":143,"key":"6:143","ar":"ثَمَـٰنِيَةَ أَزْوَٰجٍ ۖ مِّنَ ٱلضَّأْنِ ٱثْنَيْنِ وَمِنَ ٱلْمَعْزِ ٱثْنَيْنِ ۗ قُلْ ءَآلذَّكَرَيْنِ حَرَّمَ أَمِ ٱلْأُنثَيَيْنِ أَمَّا ٱشْتَمَلَتْ عَلَيْهِ أَرْحَامُ ٱلْأُنثَيَيْنِ ۖ نَبِّـُٔونِى بِعِلْمٍ إِن كُنتُمْ صَـٰدِقِينَ","en":"[They are] eight mates - of the sheep, two and of the goats, two. Say, \"Is it the two males He has forbidden or the two females or that which the wombs of the two females contain? Inform me with knowledge, if you should be truthful.\"","tr":"Thamaniyata azwajin mina adda/niithnayni wamina almaAAzi ithnayni qul aththakarayniharrama ami alonthayayni amma ishtamalat AAalayhiarhamu alonthayayni nabbi-oonee biAAilmin in kuntum sadiqeen","juz":8,"page":147},{"s":6,"a":144,"key":"6:144","ar":"وَمِنَ ٱلْإِبِلِ ٱثْنَيْنِ وَمِنَ ٱلْبَقَرِ ٱثْنَيْنِ ۗ قُلْ ءَآلذَّكَرَيْنِ حَرَّمَ أَمِ ٱلْأُنثَيَيْنِ أَمَّا ٱشْتَمَلَتْ عَلَيْهِ أَرْحَامُ ٱلْأُنثَيَيْنِ ۖ أَمْ كُنتُمْ شُهَدَآءَ إِذْ وَصَّىٰكُمُ ٱللَّهُ بِهَـٰذَا ۚ فَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا لِّيُضِلَّ ٱلنَّاسَ بِغَيْرِ عِلْمٍ ۗ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"And of the camels, two and of the cattle, two. Say, \"Is it the two males He has forbidden or the two females or that which the wombs of the two females contain? Or were you witnesses when Allāh charged you with this? Then who is more unjust than one who invents a lie about Allāh to mislead the people by [something] other than knowledge? Indeed, Allāh does not guide the wrongdoing people.\"","tr":"Wamina al-ibili ithnayni wamina albaqariithnayni qul aththakarayni harramaami alonthayayni amma ishtamalat AAalayhi arhamualonthayayni am kuntum shuhadaa ith wassakumuAllahu bihatha faman athlamu mimmaniiftara AAala Allahi kathiban liyudillaannasa bighayri AAilmin inna Allaha layahdee alqawma aththalimeen","juz":8,"page":147},{"s":6,"a":145,"key":"6:145","ar":"قُل لَّآ أَجِدُ فِى مَآ أُوحِىَ إِلَىَّ مُحَرَّمًا عَلَىٰ طَاعِمٍ يَطْعَمُهُۥٓ إِلَّآ أَن يَكُونَ مَيْتَةً أَوْ دَمًا مَّسْفُوحًا أَوْ لَحْمَ خِنزِيرٍ فَإِنَّهُۥ رِجْسٌ أَوْ فِسْقًا أُهِلَّ لِغَيْرِ ٱللَّهِ بِهِۦ ۚ فَمَنِ ٱضْطُرَّ غَيْرَ بَاغٍ وَلَا عَادٍ فَإِنَّ رَبَّكَ غَفُورٌ رَّحِيمٌ","en":"Say, \"I do not find within that which was revealed to me [anything] forbidden to one who would eat it unless it be a dead animal or blood spilled out or the flesh of swine - for indeed, it is impure - or it be [that slaughtered in] disobedience, dedicated to other than Allāh.1 But whoever is forced [by necessity], neither desiring [it] nor transgressing [its limit], then indeed, your Lord is Forgiving and Merciful.\"","tr":"Qul la ajidu feema oohiyailayya muharraman AAala taAAimin yatAAamuhuilla an yakoona maytatan aw daman masfoohan aw lahmakhinzeerin fa-innahu rijsun aw fisqan ohilla lighayri Allahibihi famani idturra ghayra baghin wala AAadinfa-inna rabbaka ghafoorun raheem","juz":8,"page":147},{"s":6,"a":146,"key":"6:146","ar":"وَعَلَى ٱلَّذِينَ هَادُوا۟ حَرَّمْنَا كُلَّ ذِى ظُفُرٍ ۖ وَمِنَ ٱلْبَقَرِ وَٱلْغَنَمِ حَرَّمْنَا عَلَيْهِمْ شُحُومَهُمَآ إِلَّا مَا حَمَلَتْ ظُهُورُهُمَآ أَوِ ٱلْحَوَايَآ أَوْ مَا ٱخْتَلَطَ بِعَظْمٍ ۚ ذَٰلِكَ جَزَيْنَـٰهُم بِبَغْيِهِمْ ۖ وَإِنَّا لَصَـٰدِقُونَ","en":"And to those who are Jews We prohibited every animal of uncloven hoof; and of the cattle and the sheep We prohibited to them their fat, except what adheres to their backs or the entrails or what is joined with bone. [By] that We repaid them for their transgression. And indeed, We are truthful.","tr":"WaAAala allatheena hadooharramna kulla thee thufurinwamina albaqari walghanami harramnaAAalayhim shuhoomahuma illa ma hamalatthuhooruhuma awi alhawayaaw ma ikhtalata biAAathmin thalikajazaynahum bibaghyihim wa-inna lasadiqoon","juz":8,"page":147},{"s":6,"a":147,"key":"6:147","ar":"فَإِن كَذَّبُوكَ فَقُل رَّبُّكُمْ ذُو رَحْمَةٍ وَٰسِعَةٍ وَلَا يُرَدُّ بَأْسُهُۥ عَنِ ٱلْقَوْمِ ٱلْمُجْرِمِينَ","en":"So if they deny you, [O Muḥammad], say, \"Your Lord is the possessor of vast mercy; but His punishment cannot be repelled from the people who are criminals.\"","tr":"Fa-in kaththabooka faqul rabbukum thoorahmatin wasiAAatin wala yuraddu ba/suhuAAani alqawmi almujrimeen","juz":8,"page":148},{"s":6,"a":148,"key":"6:148","ar":"سَيَقُولُ ٱلَّذِينَ أَشْرَكُوا۟ لَوْ شَآءَ ٱللَّهُ مَآ أَشْرَكْنَا وَلَآ ءَابَآؤُنَا وَلَا حَرَّمْنَا مِن شَىْءٍ ۚ كَذَٰلِكَ كَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ حَتَّىٰ ذَاقُوا۟ بَأْسَنَا ۗ قُلْ هَلْ عِندَكُم مِّنْ عِلْمٍ فَتُخْرِجُوهُ لَنَآ ۖ إِن تَتَّبِعُونَ إِلَّا ٱلظَّنَّ وَإِنْ أَنتُمْ إِلَّا تَخْرُصُونَ","en":"Those who associated [others] with Allāh will say, \"If Allāh had willed, we would not have associated [anything] and neither would our fathers, nor would we have prohibited anything.\" Likewise did those before deny until they tasted Our punishment. Say, \"Do you have any knowledge that you can produce for us? You follow not except assumption, and you are not but misjudging.\"","tr":"Sayaqoolu allatheena ashrakoo law shaaAllahu ma ashrakna wala abaonawala harramna min shay-in kathalikakaththaba allatheena min qablihim hattathaqoo ba/sana qul hal AAindakum min AAilminfatukhrijoohu lana in tattabiAAoona illa aththannawa-in antum illa takhrusoon","juz":8,"page":148},{"s":6,"a":149,"key":"6:149","ar":"قُلْ فَلِلَّهِ ٱلْحُجَّةُ ٱلْبَـٰلِغَةُ ۖ فَلَوْ شَآءَ لَهَدَىٰكُمْ أَجْمَعِينَ","en":"Say, \"With Allāh is the far-reaching [i.e., conclusive] argument. If He had willed, He would have guided you all.\"","tr":"Qul falillahi alhujjatu albalighatufalaw shaa lahadakum ajmaAAeen","juz":8,"page":148},{"s":6,"a":150,"key":"6:150","ar":"قُلْ هَلُمَّ شُهَدَآءَكُمُ ٱلَّذِينَ يَشْهَدُونَ أَنَّ ٱللَّهَ حَرَّمَ هَـٰذَا ۖ فَإِن شَهِدُوا۟ فَلَا تَشْهَدْ مَعَهُمْ ۚ وَلَا تَتَّبِعْ أَهْوَآءَ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا وَٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ وَهُم بِرَبِّهِمْ يَعْدِلُونَ","en":"Say, [O Muḥammad], \"Bring forward your witnesses who will testify that Allāh has prohibited this.\" And if they testify, do not testify with them. And do not follow the desires of those who deny Our verses and those who do not believe in the Hereafter, while they equate [others] with their Lord.","tr":"Qul halumma shuhadaakumu allatheenayashhadoona anna Allaha harrama hatha fa-inshahidoo fala tashhad maAAahum wala tattabiAA ahwaaallatheena kaththaboo bi-ayatinawallatheena la yu/minoona bil-akhiratiwahum birabbihim yaAAdiloon","juz":8,"page":148},{"s":6,"a":151,"key":"6:151","ar":"۞ قُلْ تَعَالَوْا۟ أَتْلُ مَا حَرَّمَ رَبُّكُمْ عَلَيْكُمْ ۖ أَلَّا تُشْرِكُوا۟ بِهِۦ شَيْـًٔا ۖ وَبِٱلْوَٰلِدَيْنِ إِحْسَـٰنًا ۖ وَلَا تَقْتُلُوٓا۟ أَوْلَـٰدَكُم مِّنْ إِمْلَـٰقٍ ۖ نَّحْنُ نَرْزُقُكُمْ وَإِيَّاهُمْ ۖ وَلَا تَقْرَبُوا۟ ٱلْفَوَٰحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ ۖ وَلَا تَقْتُلُوا۟ ٱلنَّفْسَ ٱلَّتِى حَرَّمَ ٱللَّهُ إِلَّا بِٱلْحَقِّ ۚ ذَٰلِكُمْ وَصَّىٰكُم بِهِۦ لَعَلَّكُمْ تَعْقِلُونَ","en":"Say, \"Come, I will recite what your Lord has prohibited to you. [He commands] that you not associate anything with Him, and to parents, good treatment, and do not kill your children out of poverty; We will provide for you and them. And do not approach immoralities - what is apparent of them and what is concealed. And do not kill the soul which Allāh has forbidden [to be killed] except by [legal] right. This has He instructed you that you may use reason.\"","tr":"Qul taAAalaw atlu ma harramarabbukum AAalaykum alla tushrikoo bihi shay-an wabilwalidayniihsanan wala taqtuloo awladakum minimlaqin nahnu narzuqukum wa-iyyahum walataqraboo alfawahisha ma thahara minhawama batana wala taqtuloo annafsaallatee harrama Allahu illa bilhaqqithalikum wassakum bihi laAAallakum taAAqiloon","juz":8,"page":148},{"s":6,"a":152,"key":"6:152","ar":"وَلَا تَقْرَبُوا۟ مَالَ ٱلْيَتِيمِ إِلَّا بِٱلَّتِى هِىَ أَحْسَنُ حَتَّىٰ يَبْلُغَ أَشُدَّهُۥ ۖ وَأَوْفُوا۟ ٱلْكَيْلَ وَٱلْمِيزَانَ بِٱلْقِسْطِ ۖ لَا نُكَلِّفُ نَفْسًا إِلَّا وُسْعَهَا ۖ وَإِذَا قُلْتُمْ فَٱعْدِلُوا۟ وَلَوْ كَانَ ذَا قُرْبَىٰ ۖ وَبِعَهْدِ ٱللَّهِ أَوْفُوا۟ ۚ ذَٰلِكُمْ وَصَّىٰكُم بِهِۦ لَعَلَّكُمْ تَذَكَّرُونَ","en":"And do not approach the orphan's property except in a way that is best [i.e., intending improvement] until he reaches maturity. And give full measure and weight in justice. We do not charge any soul except [with that within] its capacity. And when you speak [i.e., testify], be just, even if [it concerns] a near relative. And the covenant of Allāh fulfill. This has He instructed you that you may remember.","tr":"Wala taqraboo mala alyateemiilla billatee hiya ahsanu hattayablugha ashuddahu waawfoo alkayla walmeezana bilqistila nukallifu nafsan illa wusAAaha wa-ithaqultum faAAdiloo walaw kana tha qurbawabiAAahdi Allahi awfoo thalikum wassakumbihi laAAallakum tathakkaroon","juz":8,"page":149},{"s":6,"a":153,"key":"6:153","ar":"وَأَنَّ هَـٰذَا صِرَٰطِى مُسْتَقِيمًا فَٱتَّبِعُوهُ ۖ وَلَا تَتَّبِعُوا۟ ٱلسُّبُلَ فَتَفَرَّقَ بِكُمْ عَن سَبِيلِهِۦ ۚ ذَٰلِكُمْ وَصَّىٰكُم بِهِۦ لَعَلَّكُمْ تَتَّقُونَ","en":"And, [moreover], this is My path, which is straight, so follow it; and do not follow [other] ways, for you will be separated from His way. This has He instructed you that you may become righteous.","tr":"Waanna hatha sirateemustaqeeman fattabiAAoohu wala tattabiAAoo assubulafatafarraqa bikum AAan sabeelihi thalikum wassakumbihi laAAallakum tattaqoon","juz":8,"page":149},{"s":6,"a":154,"key":"6:154","ar":"ثُمَّ ءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ تَمَامًا عَلَى ٱلَّذِىٓ أَحْسَنَ وَتَفْصِيلًا لِّكُلِّ شَىْءٍ وَهُدًى وَرَحْمَةً لَّعَلَّهُم بِلِقَآءِ رَبِّهِمْ يُؤْمِنُونَ","en":"Then1 We gave Moses the Scripture, making complete [Our favor] upon the one who did good [i.e., Moses] and as a detailed explanation of all things and as guidance and mercy that perhaps in the meeting with their Lord they would believe.","tr":"Thumma atayna moosaalkitaba tamaman AAala allathee ahsanawatafseelan likulli shay-in wahudan warahmatanlaAAallahum biliqa-i rabbihim yu/minoon","juz":8,"page":149},{"s":6,"a":155,"key":"6:155","ar":"وَهَـٰذَا كِتَـٰبٌ أَنزَلْنَـٰهُ مُبَارَكٌ فَٱتَّبِعُوهُ وَٱتَّقُوا۟ لَعَلَّكُمْ تُرْحَمُونَ","en":"And this [Qur’ān] is a Book We have revealed [which is] blessed, so follow it and fear Allāh that you may receive mercy.","tr":"Wahatha kitabun anzalnahumubarakun fattabiAAoohu wattaqoolaAAallakum turhamoon","juz":8,"page":149},{"s":6,"a":156,"key":"6:156","ar":"أَن تَقُولُوٓا۟ إِنَّمَآ أُنزِلَ ٱلْكِتَـٰبُ عَلَىٰ طَآئِفَتَيْنِ مِن قَبْلِنَا وَإِن كُنَّا عَن دِرَاسَتِهِمْ لَغَـٰفِلِينَ","en":"[We revealed it] lest you say, \"The Scripture was only sent down to two groups before us, but we were of their study unaware,\"","tr":"An taqooloo innama onzila alkitabuAAala ta-ifatayni min qablina wa-in kunnaAAan dirasatihim laghafileen","juz":8,"page":149},{"s":6,"a":157,"key":"6:157","ar":"أَوْ تَقُولُوا۟ لَوْ أَنَّآ أُنزِلَ عَلَيْنَا ٱلْكِتَـٰبُ لَكُنَّآ أَهْدَىٰ مِنْهُمْ ۚ فَقَدْ جَآءَكُم بَيِّنَةٌ مِّن رَّبِّكُمْ وَهُدًى وَرَحْمَةٌ ۚ فَمَنْ أَظْلَمُ مِمَّن كَذَّبَ بِـَٔايَـٰتِ ٱللَّهِ وَصَدَفَ عَنْهَا ۗ سَنَجْزِى ٱلَّذِينَ يَصْدِفُونَ عَنْ ءَايَـٰتِنَا سُوٓءَ ٱلْعَذَابِ بِمَا كَانُوا۟ يَصْدِفُونَ","en":"Or lest you say, \"If only the Scripture had been revealed to us, we would have been better guided than they.\" So there has [now] come to you a clear evidence from your Lord and a guidance and mercy. Then who is more unjust than one who denies the verses of Allāh and turns away from them? We will recompense those who turn away from Our verses with the worst of punishment for their having turned away.","tr":"Aw taqooloo law anna onzila AAalaynaalkitabu lakunna ahda minhum faqad jaakumbayyinatun min rabbikum wahudan warahmatun faman athlamumimman kaththaba bi-ayati Allahi wasadafaAAanha sanajzee allatheena yasdifoona AAan ayatinasoo-a alAAathabi bima kanoo yasdifoon","juz":8,"page":149},{"s":6,"a":158,"key":"6:158","ar":"هَلْ يَنظُرُونَ إِلَّآ أَن تَأْتِيَهُمُ ٱلْمَلَـٰٓئِكَةُ أَوْ يَأْتِىَ رَبُّكَ أَوْ يَأْتِىَ بَعْضُ ءَايَـٰتِ رَبِّكَ ۗ يَوْمَ يَأْتِى بَعْضُ ءَايَـٰتِ رَبِّكَ لَا يَنفَعُ نَفْسًا إِيمَـٰنُهَا لَمْ تَكُنْ ءَامَنَتْ مِن قَبْلُ أَوْ كَسَبَتْ فِىٓ إِيمَـٰنِهَا خَيْرًا ۗ قُلِ ٱنتَظِرُوٓا۟ إِنَّا مُنتَظِرُونَ","en":"Do they [then] wait for anything except that the angels should come to them or your Lord should come or that there come some of the signs1 of your Lord? The Day that some of the signs of your Lord will come no soul will benefit from its faith as long as it had not believed before or had earned through its faith some good. Say, \"Wait. Indeed, we [also] are waiting.\"","tr":"Hal yanthuroona illaan ta/tiyahumu almala-ikatu aw ya/tiya rabbuka aw ya/tiyabaAAdu ayati rabbika yawma ya/tee baAAduayati rabbika la yanfaAAu nafsan eemanuhalam takun amanat min qablu aw kasabat fee eemanihakhayran quli intathiroo inna muntathiroon","juz":8,"page":150},{"s":6,"a":159,"key":"6:159","ar":"إِنَّ ٱلَّذِينَ فَرَّقُوا۟ دِينَهُمْ وَكَانُوا۟ شِيَعًا لَّسْتَ مِنْهُمْ فِى شَىْءٍ ۚ إِنَّمَآ أَمْرُهُمْ إِلَى ٱللَّهِ ثُمَّ يُنَبِّئُهُم بِمَا كَانُوا۟ يَفْعَلُونَ","en":"Indeed, those who have divided their religion and become sects - you, [O Muḥammad], are not [associated] with them in anything. Their affair is only [left] to Allāh; then He will inform them about what they used to do.","tr":"Inna allatheena farraqoo deenahumwakanoo shiyaAAan lasta minhum fee shay-in innamaamruhum ila Allahi thumma yunabbi-ohum bimakanoo yafAAaloon","juz":8,"page":150},{"s":6,"a":160,"key":"6:160","ar":"مَن جَآءَ بِٱلْحَسَنَةِ فَلَهُۥ عَشْرُ أَمْثَالِهَا ۖ وَمَن جَآءَ بِٱلسَّيِّئَةِ فَلَا يُجْزَىٰٓ إِلَّا مِثْلَهَا وَهُمْ لَا يُظْلَمُونَ","en":"Whoever comes [on the Day of Judgement] with a good deed will have ten times the like thereof [to his credit], and whoever comes with an evil deed will not be recompensed except the like thereof; and they will not be wronged.1","tr":"Man jaa bilhasanatifalahu AAashru amthaliha waman jaa bissayyi-atifala yujza illa mithlaha wahum layuthlamoon","juz":8,"page":150},{"s":6,"a":161,"key":"6:161","ar":"قُلْ إِنَّنِى هَدَىٰنِى رَبِّىٓ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ دِينًا قِيَمًا مِّلَّةَ إِبْرَٰهِيمَ حَنِيفًا ۚ وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ","en":"Say, \"Indeed, my Lord has guided me to a straight path - a correct religion - the way of Abraham, inclining toward truth. And he was not among those who associated others with Allāh.\"","tr":"Qul innanee hadanee rabbee ilasiratin mustaqeemin deenan qiyaman millata ibraheemahaneefan wama kana mina almushrikeen","juz":8,"page":150},{"s":6,"a":162,"key":"6:162","ar":"قُلْ إِنَّ صَلَاتِى وَنُسُكِى وَمَحْيَاىَ وَمَمَاتِى لِلَّهِ رَبِّ ٱلْعَـٰلَمِينَ","en":"Say, \"Indeed, my prayer, my rites of sacrifice, my living and my dying are for Allāh, Lord of the worlds.","tr":"Qul inna salatee wanusukeewamahyaya wamamatee lillahi rabbialAAalameen","juz":8,"page":150},{"s":6,"a":163,"key":"6:163","ar":"لَا شَرِيكَ لَهُۥ ۖ وَبِذَٰلِكَ أُمِرْتُ وَأَنَا۠ أَوَّلُ ٱلْمُسْلِمِينَ","en":"No partner has He. And this I have been commanded, and I am the first [among you] of the Muslims.\"1","tr":"La shareeka lahu wabithalikaomirtu waana awwalu almuslimeen","juz":8,"page":150},{"s":6,"a":164,"key":"6:164","ar":"قُلْ أَغَيْرَ ٱللَّهِ أَبْغِى رَبًّا وَهُوَ رَبُّ كُلِّ شَىْءٍ ۚ وَلَا تَكْسِبُ كُلُّ نَفْسٍ إِلَّا عَلَيْهَا ۚ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَىٰ ۚ ثُمَّ إِلَىٰ رَبِّكُم مَّرْجِعُكُمْ فَيُنَبِّئُكُم بِمَا كُنتُمْ فِيهِ تَخْتَلِفُونَ","en":"Say, \"Is it other than Allāh I should desire as a lord while He is the Lord of all things? And every soul earns not [blame] except against itself, and no bearer of burdens will bear the burden of another. Then to your Lord is your return, and He will inform you concerning that over which you used to differ.\"","tr":"Qul aghayra Allahi abghee rabbanwahuwa rabbu kulli shay-in wala taksibu kullu nafsin illaAAalayha wala taziru waziratun wizra okhrathumma ila rabbikum marjiAAukum fayunabbi-okum bimakuntum feehi takhtalifoon","juz":8,"page":150},{"s":6,"a":165,"key":"6:165","ar":"وَهُوَ ٱلَّذِى جَعَلَكُمْ خَلَـٰٓئِفَ ٱلْأَرْضِ وَرَفَعَ بَعْضَكُمْ فَوْقَ بَعْضٍ دَرَجَـٰتٍ لِّيَبْلُوَكُمْ فِى مَآ ءَاتَىٰكُمْ ۗ إِنَّ رَبَّكَ سَرِيعُ ٱلْعِقَابِ وَإِنَّهُۥ لَغَفُورٌ رَّحِيمٌۢ","en":"And it is He who has made you successors upon the earth and has raised some of you above others in degrees [of rank] that He may try you through what He has given you. Indeed, your Lord is swift in penalty; but indeed, He is Forgiving and Merciful.","tr":"Wahuwa allathee jaAAalakum khala-ifaal-ardi warafaAAa baAAdakum fawqa baAAdindarajatin liyabluwakum fee ma atakuminna rabbaka sareeAAu alAAiqabi wa-innahu laghafoorun raheem","juz":8,"page":150},{"s":7,"a":1,"key":"7:1","ar":" الٓمٓصٓ","en":"Alif, Lām, Meem, Ṣād.1","tr":"Alif-lam-meem-sad","juz":8,"page":151},{"s":7,"a":2,"key":"7:2","ar":"كِتَـٰبٌ أُنزِلَ إِلَيْكَ فَلَا يَكُن فِى صَدْرِكَ حَرَجٌ مِّنْهُ لِتُنذِرَ بِهِۦ وَذِكْرَىٰ لِلْمُؤْمِنِينَ","en":"[This is] a Book revealed to you, [O Muḥammad] - so let there not be in your breast distress therefrom - that you may warn thereby and as a reminder to the believers.","tr":"Kitabun onzila ilayka falayakun fee sadrika harajun minhu litunthirabihi wathikra lilmu/mineen","juz":8,"page":151},{"s":7,"a":3,"key":"7:3","ar":"ٱتَّبِعُوا۟ مَآ أُنزِلَ إِلَيْكُم مِّن رَّبِّكُمْ وَلَا تَتَّبِعُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ ۗ قَلِيلًا مَّا تَذَكَّرُونَ","en":"Follow, [O mankind], what has been revealed to you from your Lord and do not follow other than Him any allies. Little do you remember.","tr":"IttabiAAoo ma onzila ilaykum minrabbikum wala tattabiAAoo min doonihi awliyaaqaleelan ma tathakkaroon","juz":8,"page":151},{"s":7,"a":4,"key":"7:4","ar":"وَكَم مِّن قَرْيَةٍ أَهْلَكْنَـٰهَا فَجَآءَهَا بَأْسُنَا بَيَـٰتًا أَوْ هُمْ قَآئِلُونَ","en":"And how many cities have We destroyed, and Our punishment came to them at night or while they were sleeping at noon.","tr":"Wakam min qaryatin ahlaknahafajaaha ba/suna bayatan aw hum qa-iloon","juz":8,"page":151},{"s":7,"a":5,"key":"7:5","ar":"فَمَا كَانَ دَعْوَىٰهُمْ إِذْ جَآءَهُم بَأْسُنَآ إِلَّآ أَن قَالُوٓا۟ إِنَّا كُنَّا ظَـٰلِمِينَ","en":"And their declaration when Our punishment came to them was only that they said, \"Indeed, we were wrongdoers!\"","tr":"Fama kana daAAwahum ithjaahum ba/suna illa an qaloo innakunna thalimeen","juz":8,"page":151},{"s":7,"a":6,"key":"7:6","ar":"فَلَنَسْـَٔلَنَّ ٱلَّذِينَ أُرْسِلَ إِلَيْهِمْ وَلَنَسْـَٔلَنَّ ٱلْمُرْسَلِينَ","en":"Then We will surely question those to whom [a message] was sent, and We will surely question the messengers.","tr":"Falanas-alanna allatheena orsilailayhim walanas-alanna almursaleen","juz":8,"page":151},{"s":7,"a":7,"key":"7:7","ar":"فَلَنَقُصَّنَّ عَلَيْهِم بِعِلْمٍ ۖ وَمَا كُنَّا غَآئِبِينَ","en":"Then We will surely relate [their deeds] to them with knowledge, and We were not [at all] absent.","tr":"Falanaqussanna AAalayhim biAAilmin wamakunna gha-ibeen","juz":8,"page":151},{"s":7,"a":8,"key":"7:8","ar":"وَٱلْوَزْنُ يَوْمَئِذٍ ٱلْحَقُّ ۚ فَمَن ثَقُلَتْ مَوَٰزِينُهُۥ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"And the weighing [of deeds] that Day will be the truth. So those whose scales are heavy - it is they who will be the successful.","tr":"Walwaznu yawma-ithini alhaqqufaman thaqulat mawazeenuhu faola-ika humu almuflihoon","juz":8,"page":151},{"s":7,"a":9,"key":"7:9","ar":"وَمَنْ خَفَّتْ مَوَٰزِينُهُۥ فَأُو۟لَـٰٓئِكَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُم بِمَا كَانُوا۟ بِـَٔايَـٰتِنَا يَظْلِمُونَ","en":"And those whose scales are light - they are the ones who will lose themselves for what injustice they were doing toward Our verses.","tr":"Waman khaffat mawazeenuhu faola-ikaallatheena khasiroo anfusahum bima kanoo bi-ayatinayathlimoon","juz":8,"page":151},{"s":7,"a":10,"key":"7:10","ar":"وَلَقَدْ مَكَّنَّـٰكُمْ فِى ٱلْأَرْضِ وَجَعَلْنَا لَكُمْ فِيهَا مَعَـٰيِشَ ۗ قَلِيلًا مَّا تَشْكُرُونَ","en":"And We have certainly established you upon the earth and made for you therein ways of livelihood. Little are you grateful.","tr":"Walaqad makkannakum fee al-ardiwajaAAalna lakum feeha maAAayisha qaleelan matashkuroon","juz":8,"page":151},{"s":7,"a":11,"key":"7:11","ar":"وَلَقَدْ خَلَقْنَـٰكُمْ ثُمَّ صَوَّرْنَـٰكُمْ ثُمَّ قُلْنَا لِلْمَلَـٰٓئِكَةِ ٱسْجُدُوا۟ لِـَٔادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ لَمْ يَكُن مِّنَ ٱلسَّـٰجِدِينَ","en":"And We have certainly created you, [O mankind], and given you [human] form. Then We said to the angels, \"Prostrate to Adam\"; so they prostrated, except for Iblees.1 He was not of those who prostrated.","tr":"Walaqad khalaqnakum thumma sawwarnakumthumma qulna lilmala-ikati osjudoo li-adamafasajadoo illa ibleesa lam yakun mina assajideen","juz":8,"page":151},{"s":7,"a":12,"key":"7:12","ar":"قَالَ مَا مَنَعَكَ أَلَّا تَسْجُدَ إِذْ أَمَرْتُكَ ۖ قَالَ أَنَا۠ خَيْرٌ مِّنْهُ خَلَقْتَنِى مِن نَّارٍ وَخَلَقْتَهُۥ مِن طِينٍ","en":"[Allāh] said, \"What prevented you from prostrating when I commanded you?\" [Satan] said, \"I am better than him. You created me from fire and created him from clay [i.e., earth].\"","tr":"Qala ma manaAAaka allatasjuda ith amartuka qala ana khayrun minhukhalaqtanee min narin wakhalaqtahu min teen","juz":8,"page":152},{"s":7,"a":13,"key":"7:13","ar":"قَالَ فَٱهْبِطْ مِنْهَا فَمَا يَكُونُ لَكَ أَن تَتَكَبَّرَ فِيهَا فَٱخْرُجْ إِنَّكَ مِنَ ٱلصَّـٰغِرِينَ","en":"[Allāh] said, \"Descend from it [i.e., Paradise], for it is not for you to be arrogant therein. So get out; indeed, you are of the debased.\"","tr":"Qala fahbit minhafama yakoonu laka an tatakabbara feeha fakhrujinnaka mina assaghireen","juz":8,"page":152},{"s":7,"a":14,"key":"7:14","ar":"قَالَ أَنظِرْنِىٓ إِلَىٰ يَوْمِ يُبْعَثُونَ","en":"[Satan] said, \"Reprieve me until the Day they are resurrected.\"","tr":"Qala anthirnee ilayawmi yubAAathoon","juz":8,"page":152},{"s":7,"a":15,"key":"7:15","ar":"قَالَ إِنَّكَ مِنَ ٱلْمُنظَرِينَ","en":"[Allāh] said, \"Indeed, you are of those reprieved.\"","tr":"Qala innaka mina almunthareen","juz":8,"page":152},{"s":7,"a":16,"key":"7:16","ar":"قَالَ فَبِمَآ أَغْوَيْتَنِى لَأَقْعُدَنَّ لَهُمْ صِرَٰطَكَ ٱلْمُسْتَقِيمَ","en":"[Satan] said, \"Because You have put me in error, I will surely sit in wait for them [i.e., mankind] on Your straight path.","tr":"Qala fabima aghwaytaneelaaqAAudanna lahum sirataka almustaqeem","juz":8,"page":152},{"s":7,"a":17,"key":"7:17","ar":"ثُمَّ لَـَٔاتِيَنَّهُم مِّنۢ بَيْنِ أَيْدِيهِمْ وَمِنْ خَلْفِهِمْ وَعَنْ أَيْمَـٰنِهِمْ وَعَن شَمَآئِلِهِمْ ۖ وَلَا تَجِدُ أَكْثَرَهُمْ شَـٰكِرِينَ","en":"Then I will come to them from before them and from behind them and on their right and on their left, and You will not find most of them grateful [to You].\"","tr":"Thumma laatiyannahum min bayniaydeehim wamin khalfihim waAAan aymanihim waAAan shama-ilihimwala tajidu aktharahum shakireen","juz":8,"page":152},{"s":7,"a":18,"key":"7:18","ar":"قَالَ ٱخْرُجْ مِنْهَا مَذْءُومًا مَّدْحُورًا ۖ لَّمَن تَبِعَكَ مِنْهُمْ لَأَمْلَأَنَّ جَهَنَّمَ مِنكُمْ أَجْمَعِينَ","en":"[Allāh] said, \"Depart from it [i.e., Paradise], reproached and expelled. Whoever follows you among them - I will surely fill Hell with you, all together.\"","tr":"Qala okhruj minha mathoomanmadhooran laman tabiAAaka minhum laamlaanna jahannamaminkum ajmaAAeen","juz":8,"page":152},{"s":7,"a":19,"key":"7:19","ar":"وَيَـٰٓـَٔادَمُ ٱسْكُنْ أَنتَ وَزَوْجُكَ ٱلْجَنَّةَ فَكُلَا مِنْ حَيْثُ شِئْتُمَا وَلَا تَقْرَبَا هَـٰذِهِ ٱلشَّجَرَةَ فَتَكُونَا مِنَ ٱلظَّـٰلِمِينَ","en":"And \"O Adam, dwell, you and your wife, in Paradise and eat from wherever you will but do not approach this tree, lest you be among the wrongdoers.\"","tr":"Waya adamu oskun antawazawjuka aljannata fakula min haythu shi/tumawala taqraba hathihi ashshajaratafatakoona mina aththalimeen","juz":8,"page":152},{"s":7,"a":20,"key":"7:20","ar":"فَوَسْوَسَ لَهُمَا ٱلشَّيْطَـٰنُ لِيُبْدِىَ لَهُمَا مَا وُۥرِىَ عَنْهُمَا مِن سَوْءَٰتِهِمَا وَقَالَ مَا نَهَىٰكُمَا رَبُّكُمَا عَنْ هَـٰذِهِ ٱلشَّجَرَةِ إِلَّآ أَن تَكُونَا مَلَكَيْنِ أَوْ تَكُونَا مِنَ ٱلْخَـٰلِدِينَ","en":"But Satan whispered to them to make apparent to them that which was concealed from them of their private parts. He said, \"Your Lord did not forbid you this tree except that you become angels or become of the immortal.\"","tr":"Fawaswasa lahuma ashshaytanuliyubdiya lahuma ma wooriya AAanhuma minsaw-atihima waqala ma nahakumarabbukuma AAan hathihi ashshajarati illaan takoona malakayni aw takoona mina alkhalideen","juz":8,"page":152},{"s":7,"a":21,"key":"7:21","ar":"وَقَاسَمَهُمَآ إِنِّى لَكُمَا لَمِنَ ٱلنَّـٰصِحِينَ","en":"And he swore [by Allāh] to them, \"Indeed, I am to you from among the sincere advisors.\"","tr":"Waqasamahuma innee lakumalamina annasiheen","juz":8,"page":152},{"s":7,"a":22,"key":"7:22","ar":"فَدَلَّىٰهُمَا بِغُرُورٍ ۚ فَلَمَّا ذَاقَا ٱلشَّجَرَةَ بَدَتْ لَهُمَا سَوْءَٰتُهُمَا وَطَفِقَا يَخْصِفَانِ عَلَيْهِمَا مِن وَرَقِ ٱلْجَنَّةِ ۖ وَنَادَىٰهُمَا رَبُّهُمَآ أَلَمْ أَنْهَكُمَا عَن تِلْكُمَا ٱلشَّجَرَةِ وَأَقُل لَّكُمَآ إِنَّ ٱلشَّيْطَـٰنَ لَكُمَا عَدُوٌّ مُّبِينٌ","en":"So he made them fall, through deception. And when they tasted of the tree, their private parts became apparent to them, and they began to fasten together over themselves from the leaves of Paradise. And their Lord called to them, \"Did I not forbid you from that tree and tell you that Satan is to you a clear enemy?\"","tr":"Fadallahuma bighuroorin falammathaqa ashshajarata badat lahuma saw-atuhumawatafiqa yakhsifani AAalayhimamin waraqi aljannati wanadahuma rabbuhumaalam anhakuma AAan tilkuma ashshajaratiwaaqul lakuma inna ashshaytana lakumaAAaduwwun mubeen","juz":8,"page":152},{"s":7,"a":23,"key":"7:23","ar":"قَالَا رَبَّنَا ظَلَمْنَآ أَنفُسَنَا وَإِن لَّمْ تَغْفِرْ لَنَا وَتَرْحَمْنَا لَنَكُونَنَّ مِنَ ٱلْخَـٰسِرِينَ","en":"They said, \"Our Lord, we have wronged ourselves, and if You do not forgive us and have mercy upon us, we will surely be among the losers.\"","tr":"Qala rabbana thalamnaanfusana wa-in lam taghfir lana watarhamnalanakoonanna mina alkhasireen","juz":8,"page":153},{"s":7,"a":24,"key":"7:24","ar":"قَالَ ٱهْبِطُوا۟ بَعْضُكُمْ لِبَعْضٍ عَدُوٌّ ۖ وَلَكُمْ فِى ٱلْأَرْضِ مُسْتَقَرٌّ وَمَتَـٰعٌ إِلَىٰ حِينٍ","en":"[Allāh] said, \"Descend, being to one another enemies. And for you on the earth is a place of settlement and enjoyment [i.e., provision] for a time.\"","tr":"Qala ihbitoo baAAdukumlibaAAdin AAaduwwun walakum fee al-ardi mustaqarrunwamataAAun ila heen","juz":8,"page":153},{"s":7,"a":25,"key":"7:25","ar":"قَالَ فِيهَا تَحْيَوْنَ وَفِيهَا تَمُوتُونَ وَمِنْهَا تُخْرَجُونَ","en":"He said, \"Therein you will live, and therein you will die, and from it you will be brought forth.\"","tr":"Qala feeha tahyawnawafeeha tamootoona waminha tukhrajoon","juz":8,"page":153},{"s":7,"a":26,"key":"7:26","ar":"يَـٰبَنِىٓ ءَادَمَ قَدْ أَنزَلْنَا عَلَيْكُمْ لِبَاسًا يُوَٰرِى سَوْءَٰتِكُمْ وَرِيشًا ۖ وَلِبَاسُ ٱلتَّقْوَىٰ ذَٰلِكَ خَيْرٌ ۚ ذَٰلِكَ مِنْ ءَايَـٰتِ ٱللَّهِ لَعَلَّهُمْ يَذَّكَّرُونَ","en":"O children of Adam, We have bestowed upon you clothing to conceal your private parts and as adornment. But the clothing of righteousness - that is best. That is from the signs of Allāh that perhaps they will remember.","tr":"Ya banee adama qad anzalnaAAalaykum libasan yuwaree saw-atikumwareeshan walibasu attaqwa thalikakhayrun thalika min ayati AllahilaAAallahum yaththakkaroon","juz":8,"page":153},{"s":7,"a":27,"key":"7:27","ar":"يَـٰبَنِىٓ ءَادَمَ لَا يَفْتِنَنَّكُمُ ٱلشَّيْطَـٰنُ كَمَآ أَخْرَجَ أَبَوَيْكُم مِّنَ ٱلْجَنَّةِ يَنزِعُ عَنْهُمَا لِبَاسَهُمَا لِيُرِيَهُمَا سَوْءَٰتِهِمَآ ۗ إِنَّهُۥ يَرَىٰكُمْ هُوَ وَقَبِيلُهُۥ مِنْ حَيْثُ لَا تَرَوْنَهُمْ ۗ إِنَّا جَعَلْنَا ٱلشَّيَـٰطِينَ أَوْلِيَآءَ لِلَّذِينَ لَا يُؤْمِنُونَ","en":"O children of Adam, let not Satan tempt you as he removed your parents from Paradise, stripping them of their clothing1 to show them their private parts. Indeed, he sees you, he and his tribe, from where you do not see them. Indeed, We have made the devils allies to those who do not believe.","tr":"Ya banee adama layaftinannakumu ashshaytanu kama akhrajaabawaykum mina aljannati yanziAAu AAanhuma libasahumaliyuriyahuma saw-atihima innahu yarakumhuwa waqabeeluhu min haythu la tarawnahum innajaAAalna ashshayateena awliyaa lillatheenala yu/minoon","juz":8,"page":153},{"s":7,"a":28,"key":"7:28","ar":"وَإِذَا فَعَلُوا۟ فَـٰحِشَةً قَالُوا۟ وَجَدْنَا عَلَيْهَآ ءَابَآءَنَا وَٱللَّهُ أَمَرَنَا بِهَا ۗ قُلْ إِنَّ ٱللَّهَ لَا يَأْمُرُ بِٱلْفَحْشَآءِ ۖ أَتَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ","en":"And when they commit an immorality, they say, \"We found our fathers doing it, and Allāh has ordered us to do it.\" Say, \"Indeed, Allāh does not order immorality. Do you say about Allāh that which you do not know?\"","tr":"Wa-itha faAAaloo fahishatan qaloowajadna AAalayha abaana wallahuamarana biha qul inna Allaha laya/muru bilfahsha-i ataqooloona AAalaAllahi ma la taAAlamoon","juz":8,"page":153},{"s":7,"a":29,"key":"7:29","ar":"قُلْ أَمَرَ رَبِّى بِٱلْقِسْطِ ۖ وَأَقِيمُوا۟ وُجُوهَكُمْ عِندَ كُلِّ مَسْجِدٍ وَٱدْعُوهُ مُخْلِصِينَ لَهُ ٱلدِّينَ ۚ كَمَا بَدَأَكُمْ تَعُودُونَ","en":"Say, [O Muḥammad], \"My Lord has ordered justice and that you direct yourselves [to the Qiblah] at every place [or time] of prostration, and invoke Him, sincere to Him in religion.\" Just as He originated you, you will return [to life] -","tr":"Qul amara rabbee bilqistiwaaqeemoo wujoohakum AAinda kulli masjidin wadAAoohumukhliseena lahu addeena kama badaakumtaAAoodoon","juz":8,"page":153},{"s":7,"a":30,"key":"7:30","ar":"فَرِيقًا هَدَىٰ وَفَرِيقًا حَقَّ عَلَيْهِمُ ٱلضَّلَـٰلَةُ ۗ إِنَّهُمُ ٱتَّخَذُوا۟ ٱلشَّيَـٰطِينَ أَوْلِيَآءَ مِن دُونِ ٱللَّهِ وَيَحْسَبُونَ أَنَّهُم مُّهْتَدُونَ","en":"A group [of you] He guided, and a group deserved [to be in] error. Indeed, they [i.e., the latter] had taken the devils as allies instead of Allāh while they thought that they were guided.","tr":"Fareeqan hada wafareeqan haqqaAAalayhimu addalalatu innahumu ittakhathooashshayateena awliyaa min dooni Allahiwayahsaboona annahum muhtadoon","juz":8,"page":153},{"s":7,"a":31,"key":"7:31","ar":"۞ يَـٰبَنِىٓ ءَادَمَ خُذُوا۟ زِينَتَكُمْ عِندَ كُلِّ مَسْجِدٍ وَكُلُوا۟ وَٱشْرَبُوا۟ وَلَا تُسْرِفُوٓا۟ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُسْرِفِينَ","en":"O children of Adam, take your adornment [i.e., wear your clothing] at every masjid,1 and eat and drink, but be not excessive. Indeed, He likes not those who commit excess.","tr":"Ya banee adama khuthoozeenatakum AAinda kulli masjidin wakuloo washraboo walatusrifoo innahu la yuhibbu almusrifeen","juz":8,"page":154},{"s":7,"a":32,"key":"7:32","ar":"قُلْ مَنْ حَرَّمَ زِينَةَ ٱللَّهِ ٱلَّتِىٓ أَخْرَجَ لِعِبَادِهِۦ وَٱلطَّيِّبَـٰتِ مِنَ ٱلرِّزْقِ ۚ قُلْ هِىَ لِلَّذِينَ ءَامَنُوا۟ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا خَالِصَةً يَوْمَ ٱلْقِيَـٰمَةِ ۗ كَذَٰلِكَ نُفَصِّلُ ٱلْـَٔايَـٰتِ لِقَوْمٍ يَعْلَمُونَ","en":"Say, \"Who has forbidden the adornment of [i.e., from] Allāh which He has produced for His servants and the good [lawful] things of provision?\" Say, \"They are for those who believed during the life of this world, exclusively [for them] on the Day of Resurrection.\" Thus do We detail the verses for a people who know.","tr":"Qul man harrama zeenata Allahiallatee akhraja liAAibadihi wattayyibatimina arrizqi qul hiya lillatheena amanoofee alhayati addunya khalisatanyawma alqiyamati kathalika nufassilu al-ayatiliqawmin yaAAlamoon","juz":8,"page":154},{"s":7,"a":33,"key":"7:33","ar":"قُلْ إِنَّمَا حَرَّمَ رَبِّىَ ٱلْفَوَٰحِشَ مَا ظَهَرَ مِنْهَا وَمَا بَطَنَ وَٱلْإِثْمَ وَٱلْبَغْىَ بِغَيْرِ ٱلْحَقِّ وَأَن تُشْرِكُوا۟ بِٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ سُلْطَـٰنًا وَأَن تَقُولُوا۟ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ","en":"Say, \"My Lord has only forbidden immoralities - what is apparent of them and what is concealed - and sin,1 and oppression without right, and that you associate with Allāh that for which He has not sent down authority, and that you say about Allāh that which you do not know.\"","tr":"Qul innama harrama rabbiyaalfawahisha ma thahara minhawama batana wal-ithma walbaghyabighayri alhaqqi waan tushrikoo billahi malam yunazzil bihi sultanan waan taqooloo AAala Allahima la taAAlamoon","juz":8,"page":154},{"s":7,"a":34,"key":"7:34","ar":"وَلِكُلِّ أُمَّةٍ أَجَلٌ ۖ فَإِذَا جَآءَ أَجَلُهُمْ لَا يَسْتَأْخِرُونَ سَاعَةً ۖ وَلَا يَسْتَقْدِمُونَ","en":"And for every nation is a [specified] term. So when their time has come, they will not remain behind an hour, nor will they precede [it].","tr":"Walikulli ommatin ajalun fa-itha jaaajaluhum la yasta/khiroona saAAatan walayastaqdimoon","juz":8,"page":154},{"s":7,"a":35,"key":"7:35","ar":"يَـٰبَنِىٓ ءَادَمَ إِمَّا يَأْتِيَنَّكُمْ رُسُلٌ مِّنكُمْ يَقُصُّونَ عَلَيْكُمْ ءَايَـٰتِى ۙ فَمَنِ ٱتَّقَىٰ وَأَصْلَحَ فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"O children of Adam, if there come to you messengers from among you relating to you My verses [i.e., scriptures and laws], then whoever fears Allāh and reforms - there will be no fear concerning them, nor will they grieve.","tr":"Ya banee adama immaya/tiyannakum rusulun minkum yaqussoona AAalaykum ayateefamani ittaqa waaslaha fala khawfunAAalayhim wala hum yahzanoon","juz":8,"page":154},{"s":7,"a":36,"key":"7:36","ar":"وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا وَٱسْتَكْبَرُوا۟ عَنْهَآ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"But the ones who deny Our verses and are arrogant toward them - those are the companions of the Fire; they will abide therein eternally.","tr":"Wallatheena kaththaboobi-ayatina wastakbaroo AAanhaola-ika as-habu annari humfeeha khalidoon","juz":8,"page":154},{"s":7,"a":37,"key":"7:37","ar":"فَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوْ كَذَّبَ بِـَٔايَـٰتِهِۦٓ ۚ أُو۟لَـٰٓئِكَ يَنَالُهُمْ نَصِيبُهُم مِّنَ ٱلْكِتَـٰبِ ۖ حَتَّىٰٓ إِذَا جَآءَتْهُمْ رُسُلُنَا يَتَوَفَّوْنَهُمْ قَالُوٓا۟ أَيْنَ مَا كُنتُمْ تَدْعُونَ مِن دُونِ ٱللَّهِ ۖ قَالُوا۟ ضَلُّوا۟ عَنَّا وَشَهِدُوا۟ عَلَىٰٓ أَنفُسِهِمْ أَنَّهُمْ كَانُوا۟ كَـٰفِرِينَ","en":"And who is more unjust than one who invents about Allāh a lie or denies His verses? Those will attain their portion of the decree1 until, when Our messengers [i.e., angels] come to them to take them in death, they will say, \"Where are those you used to invoke besides Allāh?\" They will say, \"They have departed from us,\" and will bear witness against themselves that they were disbelievers.","tr":"Faman athlamu mimmani iftaraAAala Allahi kathiban aw kaththababi-ayatihi ola-ika yanaluhum naseebuhummina alkitabi hatta itha jaat-humrusuluna yatawaffawnahum qaloo ayna makuntum tadAAoona min dooni Allahi qaloo dallooAAanna washahidoo AAala anfusihim annahum kanookafireen","juz":8,"page":154},{"s":7,"a":38,"key":"7:38","ar":"قَالَ ٱدْخُلُوا۟ فِىٓ أُمَمٍ قَدْ خَلَتْ مِن قَبْلِكُم مِّنَ ٱلْجِنِّ وَٱلْإِنسِ فِى ٱلنَّارِ ۖ كُلَّمَا دَخَلَتْ أُمَّةٌ لَّعَنَتْ أُخْتَهَا ۖ حَتَّىٰٓ إِذَا ٱدَّارَكُوا۟ فِيهَا جَمِيعًا قَالَتْ أُخْرَىٰهُمْ لِأُولَىٰهُمْ رَبَّنَا هَـٰٓؤُلَآءِ أَضَلُّونَا فَـَٔاتِهِمْ عَذَابًا ضِعْفًا مِّنَ ٱلنَّارِ ۖ قَالَ لِكُلٍّ ضِعْفٌ وَلَـٰكِن لَّا تَعْلَمُونَ","en":"[Allāh] will say, \"Enter among nations which had passed on before you of jinn and mankind into the Fire.\" Every time a nation enters, it will curse its sister1 until, when they have all overtaken one another therein, the last of them2 will say about the first of them,3 \"Our Lord, these had misled us, so give them a double punishment of the Fire.\" He will say, \"For each is double, but you do not know.\"","tr":"Qala odkhuloo fee omamin qad khalatmin qablikum mina aljinni wal-insi fee annarikullama dakhalat ommatun laAAanat okhtaha hattaitha iddarakoo feeha jameeAAan qalatokhrahum li-oolahum rabbana haola-iadalloona faatihim AAathaban diAAfanmina annari qala likullin diAAfunwalakin la taAAlamoon","juz":8,"page":155},{"s":7,"a":39,"key":"7:39","ar":"وَقَالَتْ أُولَىٰهُمْ لِأُخْرَىٰهُمْ فَمَا كَانَ لَكُمْ عَلَيْنَا مِن فَضْلٍ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْسِبُونَ","en":"And the first of them will say to the last of them, \"Then you had not any favor over us, so taste the punishment for what you used to earn.\"","tr":"Waqalat oolahum li-okhrahumfama kana lakum AAalayna min fadlinfathooqoo alAAathaba bima kuntum taksiboon","juz":8,"page":155},{"s":7,"a":40,"key":"7:40","ar":"إِنَّ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا وَٱسْتَكْبَرُوا۟ عَنْهَا لَا تُفَتَّحُ لَهُمْ أَبْوَٰبُ ٱلسَّمَآءِ وَلَا يَدْخُلُونَ ٱلْجَنَّةَ حَتَّىٰ يَلِجَ ٱلْجَمَلُ فِى سَمِّ ٱلْخِيَاطِ ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُجْرِمِينَ","en":"Indeed, those who deny Our verses and are arrogant toward them - the gates of Heaven will not be opened for them, nor will they enter Paradise until a camel enters into the eye of a needle [i.e., never]. And thus do We recompense the criminals.","tr":"Inna allatheena kaththaboo bi-ayatinawastakbaroo AAanha la tufattahulahum abwabu assama-i walayadkhuloona aljannata hatta yalija aljamalu feesammi alkhiyati wakathalika najzee almujrimeen","juz":8,"page":155},{"s":7,"a":41,"key":"7:41","ar":"لَهُم مِّن جَهَنَّمَ مِهَادٌ وَمِن فَوْقِهِمْ غَوَاشٍ ۚ وَكَذَٰلِكَ نَجْزِى ٱلظَّـٰلِمِينَ","en":"They will have from Hell a bed and over them coverings [of fire]. And thus do We recompense the wrongdoers.","tr":"Lahum min jahannama mihadun waminfawqihim ghawashin wakathalika najzee aththalimeen","juz":8,"page":155},{"s":7,"a":42,"key":"7:42","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَا نُكَلِّفُ نَفْسًا إِلَّا وُسْعَهَآ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْجَنَّةِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"But those who believed and did righteous deeds - We charge no soul except [within] its capacity. Those are the companions of Paradise; they will abide therein eternally.","tr":"Wallatheena amanoowaAAamiloo assalihati la nukallifunafsan illa wusAAaha ola-ika as-habualjannati hum feeha khalidoon","juz":8,"page":155},{"s":7,"a":43,"key":"7:43","ar":"وَنَزَعْنَا مَا فِى صُدُورِهِم مِّنْ غِلٍّ تَجْرِى مِن تَحْتِهِمُ ٱلْأَنْهَـٰرُ ۖ وَقَالُوا۟ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى هَدَىٰنَا لِهَـٰذَا وَمَا كُنَّا لِنَهْتَدِىَ لَوْلَآ أَنْ هَدَىٰنَا ٱللَّهُ ۖ لَقَدْ جَآءَتْ رُسُلُ رَبِّنَا بِٱلْحَقِّ ۖ وَنُودُوٓا۟ أَن تِلْكُمُ ٱلْجَنَّةُ أُورِثْتُمُوهَا بِمَا كُنتُمْ تَعْمَلُونَ","en":"And We will have removed whatever is within their breasts of resentment,1 [while] flowing beneath them are rivers. And they will say, \"Praise to Allāh, who has guided us to this; and we would never have been guided if Allāh had not guided us. Certainly the messengers of our Lord had come with the truth.\" And they will be called, \"This is Paradise, which you have been made to inherit for what you used to do.\"","tr":"WanazaAAna ma fee sudoorihimmin ghillin tajree min tahtihimu al-anharu waqalooalhamdu lillahi allathee hadanalihatha wama kunna linahtadiya lawlaan hadana Allahu laqad jaat rusulurabbina bilhaqqi wanoodoo an tilkumualjannatu oorithtumooha bima kuntum taAAmaloon","juz":8,"page":155},{"s":7,"a":44,"key":"7:44","ar":"وَنَادَىٰٓ أَصْحَـٰبُ ٱلْجَنَّةِ أَصْحَـٰبَ ٱلنَّارِ أَن قَدْ وَجَدْنَا مَا وَعَدَنَا رَبُّنَا حَقًّا فَهَلْ وَجَدتُّم مَّا وَعَدَ رَبُّكُمْ حَقًّا ۖ قَالُوا۟ نَعَمْ ۚ فَأَذَّنَ مُؤَذِّنٌۢ بَيْنَهُمْ أَن لَّعْنَةُ ٱللَّهِ عَلَى ٱلظَّـٰلِمِينَ","en":"And the companions of Paradise will call out to the companions of the Fire, \"We have already found what our Lord promised us to be true. Have you found what your Lord promised to be true?\" They will say, \"Yes.\" Then an announcer will announce among them, \"The curse of Allāh shall be upon the wrongdoers","tr":"Wanada as-habualjannati as-haba annari an qadwajadna ma waAAadana rabbuna haqqanfahal wajadtum ma waAAada rabbukum haqqan qaloonaAAam faaththana mu-aththinun baynahum an laAAnatuAllahi AAala aththalimeen","juz":8,"page":156},{"s":7,"a":45,"key":"7:45","ar":"ٱلَّذِينَ يَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَيَبْغُونَهَا عِوَجًا وَهُم بِٱلْـَٔاخِرَةِ كَـٰفِرُونَ","en":"Who averted [people] from the way of Allāh and sought to make it [seem] deviant while they were, concerning the Hereafter, disbelievers.\"","tr":"Allatheena yasuddoona AAansabeeli Allahi wayabghoonaha AAiwajan wahum bil-akhiratikafiroon","juz":8,"page":156},{"s":7,"a":46,"key":"7:46","ar":"وَبَيْنَهُمَا حِجَابٌ ۚ وَعَلَى ٱلْأَعْرَافِ رِجَالٌ يَعْرِفُونَ كُلًّۢا بِسِيمَىٰهُمْ ۚ وَنَادَوْا۟ أَصْحَـٰبَ ٱلْجَنَّةِ أَن سَلَـٰمٌ عَلَيْكُمْ ۚ لَمْ يَدْخُلُوهَا وَهُمْ يَطْمَعُونَ","en":"And between them will be a partition [i.e., wall], and on [its] elevations are men1 who recognize all2 by their mark. And they call out to the companions of Paradise, \"Peace be upon you.\" They have not [yet] entered it, but they long intensely.","tr":"Wabaynahuma hijabunwaAAala al-aAArafi rijalun yaAArifoonakullan biseemahum wanadaw as-habaaljannati an salamun AAalaykum lam yadkhuloohawahum yatmaAAoon","juz":8,"page":156},{"s":7,"a":47,"key":"7:47","ar":"۞ وَإِذَا صُرِفَتْ أَبْصَـٰرُهُمْ تِلْقَآءَ أَصْحَـٰبِ ٱلنَّارِ قَالُوا۟ رَبَّنَا لَا تَجْعَلْنَا مَعَ ٱلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"And when their eyes are turned toward the companions of the Fire, they say, \"Our Lord, do not place us with the wrongdoing people.\"","tr":"Wa-itha surifat absaruhumtilqaa as-habi annari qaloorabbana la tajAAalna maAAa alqawmi aththalimeen","juz":8,"page":156},{"s":7,"a":48,"key":"7:48","ar":"وَنَادَىٰٓ أَصْحَـٰبُ ٱلْأَعْرَافِ رِجَالًا يَعْرِفُونَهُم بِسِيمَىٰهُمْ قَالُوا۟ مَآ أَغْنَىٰ عَنكُمْ جَمْعُكُمْ وَمَا كُنتُمْ تَسْتَكْبِرُونَ","en":"And the companions of the Elevations will call to men [within Hell] whom they recognize by their mark, saying, \"Of no avail to you was your gathering1 and [the fact] that you were arrogant.\"","tr":"Wanada as-habual-aAArafi rijalan yaAArifoonahum biseemahumqaloo ma aghna AAankum jamAAukum wamakuntum tastakbiroon","juz":8,"page":156},{"s":7,"a":49,"key":"7:49","ar":"أَهَـٰٓؤُلَآءِ ٱلَّذِينَ أَقْسَمْتُمْ لَا يَنَالُهُمُ ٱللَّهُ بِرَحْمَةٍ ۚ ٱدْخُلُوا۟ ٱلْجَنَّةَ لَا خَوْفٌ عَلَيْكُمْ وَلَآ أَنتُمْ تَحْزَنُونَ","en":"[Allāh will say], \"Are these1 the ones whom you [inhabitants of Hell] swore that Allāh would never offer them mercy? Enter Paradise, [O people of the Elevations]. No fear will there be concerning you, nor will you grieve.\"","tr":"Ahaola-i allatheenaaqsamtum la yanaluhumu Allahu birahmatinodkhuloo aljannata la khawfun AAalaykum wala antumtahzanoon","juz":8,"page":156},{"s":7,"a":50,"key":"7:50","ar":"وَنَادَىٰٓ أَصْحَـٰبُ ٱلنَّارِ أَصْحَـٰبَ ٱلْجَنَّةِ أَنْ أَفِيضُوا۟ عَلَيْنَا مِنَ ٱلْمَآءِ أَوْ مِمَّا رَزَقَكُمُ ٱللَّهُ ۚ قَالُوٓا۟ إِنَّ ٱللَّهَ حَرَّمَهُمَا عَلَى ٱلْكَـٰفِرِينَ","en":"And the companions of the Fire will call to the companions of Paradise, \"Pour upon us some water or from whatever Allāh has provided you.\" They will say, \"Indeed, Allāh has forbidden them both to the disbelievers","tr":"Wanada as-habu anarias-haba aljannati an afeedoo AAalaynamina alma-i aw mimma razaqakumu Allahu qalooinna Allaha harramahuma AAala alkafireen","juz":8,"page":156},{"s":7,"a":51,"key":"7:51","ar":"ٱلَّذِينَ ٱتَّخَذُوا۟ دِينَهُمْ لَهْوًا وَلَعِبًا وَغَرَّتْهُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا ۚ فَٱلْيَوْمَ نَنسَىٰهُمْ كَمَا نَسُوا۟ لِقَآءَ يَوْمِهِمْ هَـٰذَا وَمَا كَانُوا۟ بِـَٔايَـٰتِنَا يَجْحَدُونَ","en":"Who took their religion as distraction and amusement and whom the worldly life deluded.\" So today We will forget them just as they forgot the meeting of this Day of theirs and for having rejected Our verses.","tr":"Allatheena ittakhathoodeenahum lahwan walaAAiban wagharrat-humu alhayatuaddunya falyawma nansahum kamanasoo liqaa yawmihim hatha wama kanoobi-ayatina yajhadoon","juz":8,"page":156},{"s":7,"a":52,"key":"7:52","ar":"وَلَقَدْ جِئْنَـٰهُم بِكِتَـٰبٍ فَصَّلْنَـٰهُ عَلَىٰ عِلْمٍ هُدًى وَرَحْمَةً لِّقَوْمٍ يُؤْمِنُونَ","en":"And We had certainly brought them a Book which We detailed by knowledge - as guidance and mercy to a people who believe.","tr":"Walaqad ji/nahum bikitabin fassalnahuAAala AAilmin hudan warahmatan liqawmin yu/minoon","juz":8,"page":157},{"s":7,"a":53,"key":"7:53","ar":"هَلْ يَنظُرُونَ إِلَّا تَأْوِيلَهُۥ ۚ يَوْمَ يَأْتِى تَأْوِيلُهُۥ يَقُولُ ٱلَّذِينَ نَسُوهُ مِن قَبْلُ قَدْ جَآءَتْ رُسُلُ رَبِّنَا بِٱلْحَقِّ فَهَل لَّنَا مِن شُفَعَآءَ فَيَشْفَعُوا۟ لَنَآ أَوْ نُرَدُّ فَنَعْمَلَ غَيْرَ ٱلَّذِى كُنَّا نَعْمَلُ ۚ قَدْ خَسِرُوٓا۟ أَنفُسَهُمْ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ","en":"Do they await except its result?1 The Day its result comes, those who had ignored it before will say, \"The messengers of our Lord had come with the truth, so are there [now] any intercessors to intercede for us or could we be sent back to do other than what we used to do?\" They will have lost themselves, and lost from them is what they used to invent.","tr":"Hal yanthuroona illata/weelahu yawma ya/tee ta/weeluhu yaqoolu allatheenanasoohu min qablu qad jaat rusulu rabbina bilhaqqifahal lana min shufaAAaa fayashfaAAoo lanaaw nuraddu fanaAAmala ghayra allathee kunnanaAAmalu qad khasiroo anfusahum wadalla AAanhum makanoo yaftaroon","juz":8,"page":157},{"s":7,"a":54,"key":"7:54","ar":"إِنَّ رَبَّكُمُ ٱللَّهُ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ فِى سِتَّةِ أَيَّامٍ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ يُغْشِى ٱلَّيْلَ ٱلنَّهَارَ يَطْلُبُهُۥ حَثِيثًا وَٱلشَّمْسَ وَٱلْقَمَرَ وَٱلنُّجُومَ مُسَخَّرَٰتٍۭ بِأَمْرِهِۦٓ ۗ أَلَا لَهُ ٱلْخَلْقُ وَٱلْأَمْرُ ۗ تَبَارَكَ ٱللَّهُ رَبُّ ٱلْعَـٰلَمِينَ","en":"Indeed, your Lord is Allāh, who created the heavens and earth in six days and then established Himself above the Throne.1 He covers the night with the day, [another night] chasing it rapidly; and [He created] the sun, the moon, and the stars, subjected by His command. Unquestionably, His is the creation and the command; blessed is Allāh, Lord of the worlds.","tr":"Inna rabbakumu Allahu allatheekhalaqa assamawati wal-ardafee sittati ayyamin thumma istawa AAalaalAAarshi yughshee allayla annahara yatlubuhuhatheethan washshamsa walqamara wannujoomamusakhkharatin bi-amrihi ala lahu alkhalqu wal-amrutabaraka Allahu rabbu alAAalameen","juz":8,"page":157},{"s":7,"a":55,"key":"7:55","ar":"ٱدْعُوا۟ رَبَّكُمْ تَضَرُّعًا وَخُفْيَةً ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُعْتَدِينَ","en":"Call upon your Lord in humility and privately; indeed, He does not like transgressors.1","tr":"OdAAoo rabbakum tadarruAAanwakhufyatan innahu la yuhibbu almuAAtadeen","juz":8,"page":157},{"s":7,"a":56,"key":"7:56","ar":"وَلَا تُفْسِدُوا۟ فِى ٱلْأَرْضِ بَعْدَ إِصْلَـٰحِهَا وَٱدْعُوهُ خَوْفًا وَطَمَعًا ۚ إِنَّ رَحْمَتَ ٱللَّهِ قَرِيبٌ مِّنَ ٱلْمُحْسِنِينَ","en":"And cause not corruption upon the earth after its reformation. And invoke Him in fear and aspiration. Indeed, the mercy of Allāh is near to the doers of good.","tr":"Wala tufsidoo fee al-ardibaAAda islahiha wadAAoohu khawfan watamaAAaninna rahmata Allahi qareebun mina almuhsineen","juz":8,"page":157},{"s":7,"a":57,"key":"7:57","ar":"وَهُوَ ٱلَّذِى يُرْسِلُ ٱلرِّيَـٰحَ بُشْرًۢا بَيْنَ يَدَىْ رَحْمَتِهِۦ ۖ حَتَّىٰٓ إِذَآ أَقَلَّتْ سَحَابًا ثِقَالًا سُقْنَـٰهُ لِبَلَدٍ مَّيِّتٍ فَأَنزَلْنَا بِهِ ٱلْمَآءَ فَأَخْرَجْنَا بِهِۦ مِن كُلِّ ٱلثَّمَرَٰتِ ۚ كَذَٰلِكَ نُخْرِجُ ٱلْمَوْتَىٰ لَعَلَّكُمْ تَذَكَّرُونَ","en":"And it is He who sends the winds as good tidings before His mercy [i.e., rainfall] until, when they have carried heavy rainclouds, We drive them to a dead land and We send down rain therein and bring forth thereby [some] of all the fruits. Thus will We bring forth the dead; perhaps you may be reminded.","tr":"Wahuwa allathee yursilu arriyahabushran bayna yaday rahmatihi hatta ithaaqallat sahaban thiqalan suqnahu libaladinmayyitin faanzalna bihi almaa faakhrajnabihi min kulli aththamarati kathalikanukhriju almawta laAAallakum tathakkaroon","juz":8,"page":157},{"s":7,"a":58,"key":"7:58","ar":"وَٱلْبَلَدُ ٱلطَّيِّبُ يَخْرُجُ نَبَاتُهُۥ بِإِذْنِ رَبِّهِۦ ۖ وَٱلَّذِى خَبُثَ لَا يَخْرُجُ إِلَّا نَكِدًا ۚ كَذَٰلِكَ نُصَرِّفُ ٱلْـَٔايَـٰتِ لِقَوْمٍ يَشْكُرُونَ","en":"And the good land - its vegetation emerges by permission of its Lord; but that which is bad - nothing emerges except sparsely, with difficulty. Thus do We diversify the signs for a people who are grateful.","tr":"Walbaladu attayyibuyakhruju nabatuhu bi-ithni rabbihi wallatheekhabutha la yakhruju illa nakidan kathalikanusarrifu al-ayati liqawmin yashkuroon","juz":8,"page":158},{"s":7,"a":59,"key":"7:59","ar":"لَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَقَالَ يَـٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَـٰهٍ غَيْرُهُۥٓ إِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ عَظِيمٍ","en":"We had certainly sent Noah to his people, and he said, \"O my people, worship Allāh; you have no deity other than Him. Indeed, I fear for you the punishment of a tremendous Day.\"","tr":"Laqad arsalna noohan ilaqawmihi faqala ya qawmi oAAbudoo Allaha malakum min ilahin ghayruhu innee akhafu AAalaykumAAathaba yawmin AAatheem","juz":8,"page":158},{"s":7,"a":60,"key":"7:60","ar":"قَالَ ٱلْمَلَأُ مِن قَوْمِهِۦٓ إِنَّا لَنَرَىٰكَ فِى ضَلَـٰلٍ مُّبِينٍ","en":"Said the eminent among his people, \"Indeed, we see you in clear error.\"","tr":"Qala almalao min qawmihi innalanaraka fee dalalin mubeen","juz":8,"page":158},{"s":7,"a":61,"key":"7:61","ar":"قَالَ يَـٰقَوْمِ لَيْسَ بِى ضَلَـٰلَةٌ وَلَـٰكِنِّى رَسُولٌ مِّن رَّبِّ ٱلْعَـٰلَمِينَ","en":"[Noah] said, \"O my people, there is not error in me, but I am a messenger from the Lord of the worlds.","tr":"Qala ya qawmi laysa bee dalalatunwalakinnee rasoolun min rabbi alAAalameen","juz":8,"page":158},{"s":7,"a":62,"key":"7:62","ar":"أُبَلِّغُكُمْ رِسَـٰلَـٰتِ رَبِّى وَأَنصَحُ لَكُمْ وَأَعْلَمُ مِنَ ٱللَّهِ مَا لَا تَعْلَمُونَ","en":"I convey to you the messages of my Lord and advise you; and I know from Allāh what you do not know.","tr":"Oballighukum risalati rabbeewaansahu lakum waaAAlamu mina Allahi mala taAAlamoon","juz":8,"page":158},{"s":7,"a":63,"key":"7:63","ar":"أَوَعَجِبْتُمْ أَن جَآءَكُمْ ذِكْرٌ مِّن رَّبِّكُمْ عَلَىٰ رَجُلٍ مِّنكُمْ لِيُنذِرَكُمْ وَلِتَتَّقُوا۟ وَلَعَلَّكُمْ تُرْحَمُونَ","en":"Then do you wonder that there has come to you a reminder from your Lord through a man from among you, that he may warn you and that you may fear Allāh so you might receive mercy?\"","tr":"Awa AAajibtum an jaakum thikrunmin rabbikum AAala rajulin minkum liyunthirakumwalitattaqoo walaAAallakum turhamoon","juz":8,"page":158},{"s":7,"a":64,"key":"7:64","ar":"فَكَذَّبُوهُ فَأَنجَيْنَـٰهُ وَٱلَّذِينَ مَعَهُۥ فِى ٱلْفُلْكِ وَأَغْرَقْنَا ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَآ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًا عَمِينَ","en":"But they denied him, so We saved him and those who were with him in the ship. And We drowned those who denied Our signs. Indeed, they were a blind people.1","tr":"Fakaththaboohu faanjaynahu wallatheenamaAAahu fee alfulki waaghraqna allatheena kaththaboobi-ayatina innahum kanoo qawmanAAameen","juz":8,"page":158},{"s":7,"a":65,"key":"7:65","ar":"۞ وَإِلَىٰ عَادٍ أَخَاهُمْ هُودًا ۗ قَالَ يَـٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَـٰهٍ غَيْرُهُۥٓ ۚ أَفَلَا تَتَّقُونَ","en":"And to the ʿAad [We sent] their brother Hūd. He said, \"O my people, worship Allāh; you have no deity other than Him. Then will you not fear Him?\"","tr":"Wa-ila AAadin akhahumhoodan qala ya qawmi oAAbudoo Allaha malakum min ilahin ghayruhu afala tattaqoon","juz":8,"page":158},{"s":7,"a":66,"key":"7:66","ar":"قَالَ ٱلْمَلَأُ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦٓ إِنَّا لَنَرَىٰكَ فِى سَفَاهَةٍ وَإِنَّا لَنَظُنُّكَ مِنَ ٱلْكَـٰذِبِينَ","en":"Said the eminent ones who disbelieved among his people, \"Indeed, we see you in foolishness, and indeed, we think you are of the liars.\"","tr":"Qala almalao allatheenakafaroo min qawmihi inna lanaraka fee safahatinwa-inna lanathunnuka mina alkathibeen","juz":8,"page":158},{"s":7,"a":67,"key":"7:67","ar":"قَالَ يَـٰقَوْمِ لَيْسَ بِى سَفَاهَةٌ وَلَـٰكِنِّى رَسُولٌ مِّن رَّبِّ ٱلْعَـٰلَمِينَ","en":"[Hūd] said, \"O my people, there is not foolishness in me, but I am a messenger from the Lord of the worlds.","tr":"Qala ya qawmi laysa bee safahatunwalakinnee rasoolun min rabbi alAAalameen","juz":8,"page":158},{"s":7,"a":68,"key":"7:68","ar":"أُبَلِّغُكُمْ رِسَـٰلَـٰتِ رَبِّى وَأَنَا۠ لَكُمْ نَاصِحٌ أَمِينٌ","en":"I convey to you the messages of my Lord, and I am to you a trustworthy adviser.","tr":"Oballighukum risalati rabbeewaana lakum nasihun ameen","juz":8,"page":159},{"s":7,"a":69,"key":"7:69","ar":"أَوَعَجِبْتُمْ أَن جَآءَكُمْ ذِكْرٌ مِّن رَّبِّكُمْ عَلَىٰ رَجُلٍ مِّنكُمْ لِيُنذِرَكُمْ ۚ وَٱذْكُرُوٓا۟ إِذْ جَعَلَكُمْ خُلَفَآءَ مِنۢ بَعْدِ قَوْمِ نُوحٍ وَزَادَكُمْ فِى ٱلْخَلْقِ بَصْۜطَةً ۖ فَٱذْكُرُوٓا۟ ءَالَآءَ ٱللَّهِ لَعَلَّكُمْ تُفْلِحُونَ","en":"Then do you wonder that there has come to you a reminder from your Lord through a man from among you, that he may warn you? And remember when He made you successors after the people of Noah and increased you in stature extensively. So remember the favors of Allāh that you might succeed.\"","tr":"Awa AAajibtum an jaakum thikrunmin rabbikum AAala rajulin minkum liyunthirakum wathkurooith jaAAalakum khulafaa min baAAdi qawmi noohinwazadakum fee alkhalqi bastatan fathkurooalaa Allahi laAAallakum tuflihoon","juz":8,"page":159},{"s":7,"a":70,"key":"7:70","ar":"قَالُوٓا۟ أَجِئْتَنَا لِنَعْبُدَ ٱللَّهَ وَحْدَهُۥ وَنَذَرَ مَا كَانَ يَعْبُدُ ءَابَآؤُنَا ۖ فَأْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ","en":"They said, \"Have you come to us that we should worship Allāh alone and leave what our fathers have worshipped? Then bring us what you promise us,1 if you should be of the truthful.\"","tr":"Qaloo aji/tana linaAAbuda Allahawahdahu wanathara ma kana yaAAbudu abaonafa/tina bima taAAiduna in kunta mina assadiqeen","juz":8,"page":159},{"s":7,"a":71,"key":"7:71","ar":"قَالَ قَدْ وَقَعَ عَلَيْكُم مِّن رَّبِّكُمْ رِجْسٌ وَغَضَبٌ ۖ أَتُجَـٰدِلُونَنِى فِىٓ أَسْمَآءٍ سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّا نَزَّلَ ٱللَّهُ بِهَا مِن سُلْطَـٰنٍ ۚ فَٱنتَظِرُوٓا۟ إِنِّى مَعَكُم مِّنَ ٱلْمُنتَظِرِينَ","en":"[Hūd] said, \"Already have defilement and anger fallen upon you from your Lord. Do you dispute with me concerning [mere] names you have named them,1 you and your fathers, for which Allāh has not sent down any authority? Then wait; indeed, I am with you among those who wait.\"","tr":"Qala qad waqaAAa AAalaykum minrabbikum rijsun waghadabun atujadiloonanee fee asma-insammaytumooha antum waabaokum manazzala Allahu biha min sultanin fantathirooinnee maAAakum mina almuntathireen","juz":8,"page":159},{"s":7,"a":72,"key":"7:72","ar":"فَأَنجَيْنَـٰهُ وَٱلَّذِينَ مَعَهُۥ بِرَحْمَةٍ مِّنَّا وَقَطَعْنَا دَابِرَ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا ۖ وَمَا كَانُوا۟ مُؤْمِنِينَ","en":"So We saved him and those with him by mercy from Us. And We eliminated those who denied Our signs, and they were not [at all] believers.","tr":"Faanjaynahu wallatheenamaAAahu birahmatin minna waqataAAna dabiraallatheena kaththaboo bi-ayatinawama kanoo mu/mineen","juz":8,"page":159},{"s":7,"a":73,"key":"7:73","ar":"وَإِلَىٰ ثَمُودَ أَخَاهُمْ صَـٰلِحًا ۗ قَالَ يَـٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَـٰهٍ غَيْرُهُۥ ۖ قَدْ جَآءَتْكُم بَيِّنَةٌ مِّن رَّبِّكُمْ ۖ هَـٰذِهِۦ نَاقَةُ ٱللَّهِ لَكُمْ ءَايَةً ۖ فَذَرُوهَا تَأْكُلْ فِىٓ أَرْضِ ٱللَّهِ ۖ وَلَا تَمَسُّوهَا بِسُوٓءٍ فَيَأْخُذَكُمْ عَذَابٌ أَلِيمٌ","en":"And to the Thamūd [We sent] their brother Ṣāliḥ. He said, \"O my people, worship Allāh; you have no deity other than Him. There has come to you clear evidence from your Lord. This is the she-camel of Allāh [sent] to you as a sign. So leave her to eat within Allāh's land and do not touch her with harm, lest there seize you a painful punishment.","tr":"Wa-ila thamooda akhahum salihanqala ya qawmi oAAbudoo Allaha malakum min ilahin ghayruhu qad jaatkum bayyinatunmin rabbikum hathihi naqatu Allahi lakum ayatanfatharooha ta/kul fee ardi Allahi walatamassooha bisoo-in faya/khuthakum AAathabunaleem","juz":8,"page":159},{"s":7,"a":74,"key":"7:74","ar":"وَٱذْكُرُوٓا۟ إِذْ جَعَلَكُمْ خُلَفَآءَ مِنۢ بَعْدِ عَادٍ وَبَوَّأَكُمْ فِى ٱلْأَرْضِ تَتَّخِذُونَ مِن سُهُولِهَا قُصُورًا وَتَنْحِتُونَ ٱلْجِبَالَ بُيُوتًا ۖ فَٱذْكُرُوٓا۟ ءَالَآءَ ٱللَّهِ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ","en":"And remember when He made you successors after the ʿAad and settled you in the land, [and] you take for yourselves palaces from its plains and carve from the mountains, homes. Then remember the favors of Allāh and do not commit abuse on the earth, spreading corruption.\"","tr":"Wathkuroo ithjaAAalakum khulafaa min baAAdi AAadin wabawwaakumfee al-ardi tattakhithoona min suhooliha qusooranwatanhitoona aljibala buyootan fathkurooalaa Allahi wala taAAthaw fee al-ardimufsideen","juz":8,"page":160},{"s":7,"a":75,"key":"7:75","ar":"قَالَ ٱلْمَلَأُ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ مِن قَوْمِهِۦ لِلَّذِينَ ٱسْتُضْعِفُوا۟ لِمَنْ ءَامَنَ مِنْهُمْ أَتَعْلَمُونَ أَنَّ صَـٰلِحًا مُّرْسَلٌ مِّن رَّبِّهِۦ ۚ قَالُوٓا۟ إِنَّا بِمَآ أُرْسِلَ بِهِۦ مُؤْمِنُونَ","en":"Said the eminent ones who were arrogant among his people to those who were oppressed - to those who believed among them, \"Do you [actually] know that Ṣāliḥ is sent from his Lord?\" They said, \"Indeed we, in that with which he was sent, are believers.\"","tr":"Qala almalao allatheenaistakbaroo min qawmihi lillatheena istudAAifooliman amana minhum ataAAlamoona anna salihanmursalun min rabbihi qaloo inna bima orsilabihi mu/minoon","juz":8,"page":160},{"s":7,"a":76,"key":"7:76","ar":"قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا بِٱلَّذِىٓ ءَامَنتُم بِهِۦ كَـٰفِرُونَ","en":"Said those who were arrogant, \"Indeed we, in that which you have believed, are disbelievers.\"","tr":"Qala allatheena istakbaroo innabillathee amantum bihi kafiroon","juz":8,"page":160},{"s":7,"a":77,"key":"7:77","ar":"فَعَقَرُوا۟ ٱلنَّاقَةَ وَعَتَوْا۟ عَنْ أَمْرِ رَبِّهِمْ وَقَالُوا۟ يَـٰصَـٰلِحُ ٱئْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلْمُرْسَلِينَ","en":"So they hamstrung the she-camel and were insolent toward the command of their Lord and said, \"O Ṣāliḥ, bring us what you promise us, if you should be of the messengers.\"","tr":"FaAAaqaroo annaqata waAAatawAAan amri rabbihim waqaloo ya salihui/tina bima taAAiduna in kunta minaalmursaleen","juz":8,"page":160},{"s":7,"a":78,"key":"7:78","ar":"فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَـٰثِمِينَ","en":"So the earthquake seized them, and they became within their home [corpses] fallen prone.","tr":"Faakhathat-humu arrajfatu faasbahoofee darihim jathimeen","juz":8,"page":160},{"s":7,"a":79,"key":"7:79","ar":"فَتَوَلَّىٰ عَنْهُمْ وَقَالَ يَـٰقَوْمِ لَقَدْ أَبْلَغْتُكُمْ رِسَالَةَ رَبِّى وَنَصَحْتُ لَكُمْ وَلَـٰكِن لَّا تُحِبُّونَ ٱلنَّـٰصِحِينَ","en":"And he [i.e., Ṣāliḥ] turned away from them and said, \"O my people, I had certainly conveyed to you the message of my Lord and advised you, but you do not like advisors.\"","tr":"Fatawalla AAanhum waqala yaqawmi laqad ablaghtukum risalata rabbee wanasahtulakum walakin la tuhibboona annasiheen","juz":8,"page":160},{"s":7,"a":80,"key":"7:80","ar":"وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ أَتَأْتُونَ ٱلْفَـٰحِشَةَ مَا سَبَقَكُم بِهَا مِنْ أَحَدٍ مِّنَ ٱلْعَـٰلَمِينَ","en":"And [We had sent] Lot when he said to his people, \"Do you commit such immorality as no one has preceded you with from among the worlds [i.e., peoples]?","tr":"Walootan ith qalaliqawmihi ata/toona alfahishata ma sabaqakum bihamin ahadin mina alAAalameen","juz":8,"page":160},{"s":7,"a":81,"key":"7:81","ar":"إِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ شَهْوَةً مِّن دُونِ ٱلنِّسَآءِ ۚ بَلْ أَنتُمْ قَوْمٌ مُّسْرِفُونَ","en":"Indeed, you approach men with desire, instead of women. Rather, you are a transgressing people.\"","tr":"Innakum lata/toona arrijalashahwatan min dooni annisa-i bal antum qawmunmusrifoon","juz":8,"page":160},{"s":7,"a":82,"key":"7:82","ar":"وَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوٓا۟ أَخْرِجُوهُم مِّن قَرْيَتِكُمْ ۖ إِنَّهُمْ أُنَاسٌ يَتَطَهَّرُونَ","en":"But the answer of his people was only that they said, \"Evict them from your city! Indeed, they are men who keep themselves pure.\"","tr":"Wama kana jawabaqawmihi illa an qaloo akhrijoohum min qaryatikuminnahum onasun yatatahharoon","juz":8,"page":161},{"s":7,"a":83,"key":"7:83","ar":"فَأَنجَيْنَـٰهُ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ كَانَتْ مِنَ ٱلْغَـٰبِرِينَ","en":"So We saved him and his family, except for his wife; she was of those who remained [with the evildoers].","tr":"Faanjaynahu waahlahu illaimraatahu kanat mina alghabireen","juz":8,"page":161},{"s":7,"a":84,"key":"7:84","ar":"وَأَمْطَرْنَا عَلَيْهِم مَّطَرًا ۖ فَٱنظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُجْرِمِينَ","en":"And We rained upon them a rain [of stones]. Then see how was the end of the criminals.","tr":"Waamtarna AAalayhim mataranfanthur kayfa kana AAaqibatualmujrimeen","juz":8,"page":161},{"s":7,"a":85,"key":"7:85","ar":"وَإِلَىٰ مَدْيَنَ أَخَاهُمْ شُعَيْبًا ۗ قَالَ يَـٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَـٰهٍ غَيْرُهُۥ ۖ قَدْ جَآءَتْكُم بَيِّنَةٌ مِّن رَّبِّكُمْ ۖ فَأَوْفُوا۟ ٱلْكَيْلَ وَٱلْمِيزَانَ وَلَا تَبْخَسُوا۟ ٱلنَّاسَ أَشْيَآءَهُمْ وَلَا تُفْسِدُوا۟ فِى ٱلْأَرْضِ بَعْدَ إِصْلَـٰحِهَا ۚ ذَٰلِكُمْ خَيْرٌ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ","en":"And to [the people of] Madyan [We sent] their brother Shuʿayb. He said, \"O my people, worship Allāh; you have no deity other than Him. There has come to you clear evidence from your Lord. So fulfill the measure and weight and do not deprive people of their due and cause not corruption upon the earth after its reformation. That is better for you, if you should be believers.","tr":"Wa-ila madyana akhahumshuAAayban qala ya qawmi oAAbudoo Allaha malakum min ilahin ghayruhu qad jaatkum bayyinatunmin rabbikum faawfoo alkayla walmeezana walatabkhasoo annasa ashyaahum walatufsidoo fee al-ardi baAAda islahiha thalikumkhayrun lakum in kuntum mu/mineen","juz":8,"page":161},{"s":7,"a":86,"key":"7:86","ar":"وَلَا تَقْعُدُوا۟ بِكُلِّ صِرَٰطٍ تُوعِدُونَ وَتَصُدُّونَ عَن سَبِيلِ ٱللَّهِ مَنْ ءَامَنَ بِهِۦ وَتَبْغُونَهَا عِوَجًا ۚ وَٱذْكُرُوٓا۟ إِذْ كُنتُمْ قَلِيلًا فَكَثَّرَكُمْ ۖ وَٱنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُفْسِدِينَ","en":"And do not sit on every path, threatening and averting from the way of Allāh those who believe in Him, seeking to make it [seem] deviant. And remember when you were few and He increased you. And see how was the end of the corrupters.","tr":"Wala taqAAudoo bikulli siratintooAAidoona watasuddoona AAan sabeeli Allahi man amanabihi watabghoonaha AAiwajan wathkuroo ithkuntum qaleelan fakaththarakum wanthurookayfa kana AAaqibatu almufsideen","juz":8,"page":161},{"s":7,"a":87,"key":"7:87","ar":"وَإِن كَانَ طَآئِفَةٌ مِّنكُمْ ءَامَنُوا۟ بِٱلَّذِىٓ أُرْسِلْتُ بِهِۦ وَطَآئِفَةٌ لَّمْ يُؤْمِنُوا۟ فَٱصْبِرُوا۟ حَتَّىٰ يَحْكُمَ ٱللَّهُ بَيْنَنَا ۚ وَهُوَ خَيْرُ ٱلْحَـٰكِمِينَ","en":"And if there should be a group among you who has believed in that with which I have been sent and a group that has not believed, then be patient until Allāh judges between us. And He is the best of judges.\"","tr":"Wa-in kana ta-ifatun minkum amanoobillathee orsiltu bihi wata-ifatun lamyu/minoo fasbiroo hatta yahkumaAllahu baynana wahuwa khayru alhakimeen","juz":8,"page":161},{"s":7,"a":88,"key":"7:88","ar":"۞ قَالَ ٱلْمَلَأُ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ مِن قَوْمِهِۦ لَنُخْرِجَنَّكَ يَـٰشُعَيْبُ وَٱلَّذِينَ ءَامَنُوا۟ مَعَكَ مِن قَرْيَتِنَآ أَوْ لَتَعُودُنَّ فِى مِلَّتِنَا ۚ قَالَ أَوَلَوْ كُنَّا كَـٰرِهِينَ","en":"Said the eminent ones who were arrogant among his people, \"We will surely evict you, O Shuʿayb, and those who have believed with you from our city, or you must return to our religion.\" He said, \"Even if we were unwilling?","tr":"Qala almalao allatheenaistakbaroo min qawmihi lanukhrijannaka ya shuAAaybu wallatheenaamanoo maAAaka min qaryatina aw lataAAoodunna feemillatina qala awa law kunna kariheen","juz":9,"page":162},{"s":7,"a":89,"key":"7:89","ar":"قَدِ ٱفْتَرَيْنَا عَلَى ٱللَّهِ كَذِبًا إِنْ عُدْنَا فِى مِلَّتِكُم بَعْدَ إِذْ نَجَّىٰنَا ٱللَّهُ مِنْهَا ۚ وَمَا يَكُونُ لَنَآ أَن نَّعُودَ فِيهَآ إِلَّآ أَن يَشَآءَ ٱللَّهُ رَبُّنَا ۚ وَسِعَ رَبُّنَا كُلَّ شَىْءٍ عِلْمًا ۚ عَلَى ٱللَّهِ تَوَكَّلْنَا ۚ رَبَّنَا ٱفْتَحْ بَيْنَنَا وَبَيْنَ قَوْمِنَا بِٱلْحَقِّ وَأَنتَ خَيْرُ ٱلْفَـٰتِحِينَ","en":"We would have invented against Allāh a lie if we returned to your religion after Allāh had saved us from it. And it is not for us to return to it except that Allāh, our Lord, should will. Our Lord has encompassed all things in knowledge. Upon Allāh we have relied. Our Lord, decide between us and our people in truth, and You are the best of those who give decision.\"","tr":"Qadi iftarayna AAala Allahikathiban in AAudna fee millatikum baAAda ithnajjana Allahu minha wamayakoonu lana an naAAooda feeha illa an yashaaAllahu rabbuna wasiAAa rabbuna kulla shay-inAAilman AAala Allahi tawakkalna rabbanaiftah baynana wabayna qawmina bilhaqqiwaanta khayru alfatiheen","juz":9,"page":162},{"s":7,"a":90,"key":"7:90","ar":"وَقَالَ ٱلْمَلَأُ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦ لَئِنِ ٱتَّبَعْتُمْ شُعَيْبًا إِنَّكُمْ إِذًا لَّخَـٰسِرُونَ","en":"Said the eminent ones who disbelieved among his people, \"If you should follow Shuʿayb, indeed, you would then be losers.\"","tr":"Waqala almalao allatheenakafaroo min qawmihi la-ini ittabaAAtum shuAAayban innakum ithanlakhasiroon","juz":9,"page":162},{"s":7,"a":91,"key":"7:91","ar":"فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَـٰثِمِينَ","en":"So the earthquake seized them, and they became within their home [corpses] fallen prone.","tr":"Faakhathat-humu arrajfatu faasbahoofee darihim jathimeen","juz":9,"page":162},{"s":7,"a":92,"key":"7:92","ar":"ٱلَّذِينَ كَذَّبُوا۟ شُعَيْبًا كَأَن لَّمْ يَغْنَوْا۟ فِيهَا ۚ ٱلَّذِينَ كَذَّبُوا۟ شُعَيْبًا كَانُوا۟ هُمُ ٱلْخَـٰسِرِينَ","en":"Those who denied Shuʿayb - it was as though they had never resided there. Those who denied Shuʿayb - it was they who were the losers.","tr":"Allatheena kaththabooshuAAayban kaan lam yaghnaw feeha allatheena kaththabooshuAAayban kanoo humu alkhasireen","juz":9,"page":162},{"s":7,"a":93,"key":"7:93","ar":"فَتَوَلَّىٰ عَنْهُمْ وَقَالَ يَـٰقَوْمِ لَقَدْ أَبْلَغْتُكُمْ رِسَـٰلَـٰتِ رَبِّى وَنَصَحْتُ لَكُمْ ۖ فَكَيْفَ ءَاسَىٰ عَلَىٰ قَوْمٍ كَـٰفِرِينَ","en":"And he [i.e., Shuʿayb] turned away from them and said, \"O my people, I had certainly conveyed to you the messages of my Lord and advised you, so how could I grieve for a disbelieving people?\"","tr":"Fatawalla AAanhum waqala yaqawmi laqad ablaghtukum risalati rabbee wanasahtulakum fakayfa asa AAala qawmin kafireen","juz":9,"page":162},{"s":7,"a":94,"key":"7:94","ar":"وَمَآ أَرْسَلْنَا فِى قَرْيَةٍ مِّن نَّبِىٍّ إِلَّآ أَخَذْنَآ أَهْلَهَا بِٱلْبَأْسَآءِ وَٱلضَّرَّآءِ لَعَلَّهُمْ يَضَّرَّعُونَ","en":"And We sent to no city a prophet [who was denied] except that We seized its people with poverty and hardship that they might humble themselves [to Allāh].","tr":"Wama arsalna fee qaryatin minnabiyyin illa akhathna ahlaha bilba/sa-iwaddarra-i laAAallahum yaddarraAAoon","juz":9,"page":162},{"s":7,"a":95,"key":"7:95","ar":"ثُمَّ بَدَّلْنَا مَكَانَ ٱلسَّيِّئَةِ ٱلْحَسَنَةَ حَتَّىٰ عَفَوا۟ وَّقَالُوا۟ قَدْ مَسَّ ءَابَآءَنَا ٱلضَّرَّآءُ وَٱلسَّرَّآءُ فَأَخَذْنَـٰهُم بَغْتَةً وَهُمْ لَا يَشْعُرُونَ","en":"Then We exchanged in place of the bad [condition], good, until they increased [and prospered] and said, \"Our fathers [also] were touched with hardship and ease.\"1 So We seized them suddenly while they did not perceive.2","tr":"Thumma baddalna makana assayyi-atialhasanata hatta AAafaw waqaloo qadmassa abaana addarraowassarrao faakhathnahum baghtatanwahum la yashAAuroon","juz":9,"page":162},{"s":7,"a":96,"key":"7:96","ar":"وَلَوْ أَنَّ أَهْلَ ٱلْقُرَىٰٓ ءَامَنُوا۟ وَٱتَّقَوْا۟ لَفَتَحْنَا عَلَيْهِم بَرَكَـٰتٍ مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ وَلَـٰكِن كَذَّبُوا۟ فَأَخَذْنَـٰهُم بِمَا كَانُوا۟ يَكْسِبُونَ","en":"And if only the people of the cities had believed and feared Allāh, We would have opened [i.e., bestowed] upon them blessings from the heaven and the earth; but they denied [the messengers], so We seized them for what they were earning.1","tr":"Walaw anna ahla alqura amanoowattaqaw lafatahna AAalayhim barakatinmina assama-i wal-ardi walakinkaththaboo faakhathnahum bima kanooyaksiboon","juz":9,"page":163},{"s":7,"a":97,"key":"7:97","ar":"أَفَأَمِنَ أَهْلُ ٱلْقُرَىٰٓ أَن يَأْتِيَهُم بَأْسُنَا بَيَـٰتًا وَهُمْ نَآئِمُونَ","en":"Then, did the people of the cities feel secure from Our punishment coming to them at night while they were asleep?","tr":"Afaamina ahlu alqura an ya/tiyahumba/suna bayatan wahum na-imoon","juz":9,"page":163},{"s":7,"a":98,"key":"7:98","ar":"أَوَأَمِنَ أَهْلُ ٱلْقُرَىٰٓ أَن يَأْتِيَهُم بَأْسُنَا ضُحًى وَهُمْ يَلْعَبُونَ","en":"Or did the people of the cities feel secure from Our punishment coming to them in the morning while they were at play?1","tr":"Awa amina ahlu alqura an ya/tiyahumba/suna duhan wahum yalAAaboon","juz":9,"page":163},{"s":7,"a":99,"key":"7:99","ar":"أَفَأَمِنُوا۟ مَكْرَ ٱللَّهِ ۚ فَلَا يَأْمَنُ مَكْرَ ٱللَّهِ إِلَّا ٱلْقَوْمُ ٱلْخَـٰسِرُونَ","en":"Then, did they feel secure from the plan of Allāh? But no one feels secure from the plan of Allāh except the losing people.","tr":"Afaaminoo makra Allahi falaya/manu makra Allahi illa alqawmu alkhasiroon","juz":9,"page":163},{"s":7,"a":100,"key":"7:100","ar":"أَوَلَمْ يَهْدِ لِلَّذِينَ يَرِثُونَ ٱلْأَرْضَ مِنۢ بَعْدِ أَهْلِهَآ أَن لَّوْ نَشَآءُ أَصَبْنَـٰهُم بِذُنُوبِهِمْ ۚ وَنَطْبَعُ عَلَىٰ قُلُوبِهِمْ فَهُمْ لَا يَسْمَعُونَ","en":"Has it not become clear to those who inherited the earth after its [previous] people that if We willed, We could afflict them for their sins? But We seal over their hearts so they do not hear.1","tr":"Awa lam yahdi lillatheena yarithoonaal-arda min baAAdi ahliha an law nashao asabnahumbithunoobihim wanatbaAAu AAala quloobihimfahum la yasmaAAoon","juz":9,"page":163},{"s":7,"a":101,"key":"7:101","ar":"تِلْكَ ٱلْقُرَىٰ نَقُصُّ عَلَيْكَ مِنْ أَنۢبَآئِهَا ۚ وَلَقَدْ جَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَـٰتِ فَمَا كَانُوا۟ لِيُؤْمِنُوا۟ بِمَا كَذَّبُوا۟ مِن قَبْلُ ۚ كَذَٰلِكَ يَطْبَعُ ٱللَّهُ عَلَىٰ قُلُوبِ ٱلْكَـٰفِرِينَ","en":"Those cities - We relate to you, [O Muḥammad], some of their news. And certainly did their messengers come to them with clear proofs, but they were not to believe in that which they had denied before.1 Thus does Allāh seal over the hearts of the disbelievers.","tr":"Tilka alqura naqussu AAalaykamin anba-iha walaqad jaat-hum rusuluhum bilbayyinatifama kanoo liyu/minoo bima kaththaboomin qablu kathalika yatbaAAu Allahu AAalaquloobi alkafireen","juz":9,"page":163},{"s":7,"a":102,"key":"7:102","ar":"وَمَا وَجَدْنَا لِأَكْثَرِهِم مِّنْ عَهْدٍ ۖ وَإِن وَجَدْنَآ أَكْثَرَهُمْ لَفَـٰسِقِينَ","en":"And We did not find for most of them any covenant;1 but indeed, We found most of them defiantly disobedient.","tr":"Wama wajadna li-aktharihimmin AAahdin wa-in wajadna aktharahum lafasiqeen","juz":9,"page":163},{"s":7,"a":103,"key":"7:103","ar":"ثُمَّ بَعَثْنَا مِنۢ بَعْدِهِم مُّوسَىٰ بِـَٔايَـٰتِنَآ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَظَلَمُوا۟ بِهَا ۖ فَٱنظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُفْسِدِينَ","en":"Then We sent after them Moses with Our signs to Pharaoh and his establishment, but they were unjust toward them.1 So see how was the end of the corrupters.","tr":"Thumma baAAathna min baAAdihim moosabi-ayatina ila firAAawna wamala-ihifathalamoo biha fanuthurkayfa kana AAaqibatu almufsideen","juz":9,"page":163},{"s":7,"a":104,"key":"7:104","ar":"وَقَالَ مُوسَىٰ يَـٰفِرْعَوْنُ إِنِّى رَسُولٌ مِّن رَّبِّ ٱلْعَـٰلَمِينَ","en":"And Moses said, \"O Pharaoh, I am a messenger from the Lord of the worlds","tr":"Waqala moosa yafirAAawnu innee rasoolun min rabbi alAAalameen","juz":9,"page":163},{"s":7,"a":105,"key":"7:105","ar":"حَقِيقٌ عَلَىٰٓ أَن لَّآ أَقُولَ عَلَى ٱللَّهِ إِلَّا ٱلْحَقَّ ۚ قَدْ جِئْتُكُم بِبَيِّنَةٍ مِّن رَّبِّكُمْ فَأَرْسِلْ مَعِىَ بَنِىٓ إِسْرَٰٓءِيلَ","en":"[Who is] obligated not to say about Allāh except the truth. I have come to you with clear evidence from your Lord, so send with me the Children of Israel.\"1","tr":"Haqeequn AAala an laaqoola AAala Allahi illa alhaqqa qadji/tukum bibayyinatin min rabbikum faarsil maAAiya banee isra-eel","juz":9,"page":164},{"s":7,"a":106,"key":"7:106","ar":"قَالَ إِن كُنتَ جِئْتَ بِـَٔايَةٍ فَأْتِ بِهَآ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ","en":"[Pharaoh] said, \"If you have come with a sign, then bring it forth, if you should be of the truthful.\"","tr":"Qala in kunta ji/ta bi-ayatinfa/ti biha in kunta mina assadiqeen","juz":9,"page":164},{"s":7,"a":107,"key":"7:107","ar":"فَأَلْقَىٰ عَصَاهُ فَإِذَا هِىَ ثُعْبَانٌ مُّبِينٌ","en":"So he [i.e., Moses] threw his staff, and suddenly it was a serpent, manifest.1","tr":"Faalqa AAasahu fa-ithahiya thuAAbanun mubeen","juz":9,"page":164},{"s":7,"a":108,"key":"7:108","ar":"وَنَزَعَ يَدَهُۥ فَإِذَا هِىَ بَيْضَآءُ لِلنَّـٰظِرِينَ","en":"And he drew out his hand; thereupon it was white [with radiance] for the observers.","tr":"WanazaAAa yadahu fa-itha hiya baydaolinnathireen","juz":9,"page":164},{"s":7,"a":109,"key":"7:109","ar":"قَالَ ٱلْمَلَأُ مِن قَوْمِ فِرْعَوْنَ إِنَّ هَـٰذَا لَسَـٰحِرٌ عَلِيمٌ","en":"Said the eminent among the people of Pharaoh, \"Indeed, this is a learned magician","tr":"Qala almalao min qawmi firAAawnainna hatha lasahirun AAaleem","juz":9,"page":164},{"s":7,"a":110,"key":"7:110","ar":"يُرِيدُ أَن يُخْرِجَكُم مِّنْ أَرْضِكُمْ ۖ فَمَاذَا تَأْمُرُونَ","en":"Who wants to expel you from your land [through magic], so what do you instruct?\"","tr":"Yureedu an yukhrijakum min ardikumfamatha ta/muroon","juz":9,"page":164},{"s":7,"a":111,"key":"7:111","ar":"قَالُوٓا۟ أَرْجِهْ وَأَخَاهُ وَأَرْسِلْ فِى ٱلْمَدَآئِنِ حَـٰشِرِينَ","en":"They said,1 \"Postpone [the matter of] him and his brother and send among the cities gatherers","tr":"Qaloo arjih waakhahu waarsilfee almada-ini hashireen","juz":9,"page":164},{"s":7,"a":112,"key":"7:112","ar":"يَأْتُوكَ بِكُلِّ سَـٰحِرٍ عَلِيمٍ","en":"Who will bring you every learned magician.\"","tr":"Ya/tooka bikulli sahirin AAaleem","juz":9,"page":164},{"s":7,"a":113,"key":"7:113","ar":"وَجَآءَ ٱلسَّحَرَةُ فِرْعَوْنَ قَالُوٓا۟ إِنَّ لَنَا لَأَجْرًا إِن كُنَّا نَحْنُ ٱلْغَـٰلِبِينَ","en":"And the magicians came to Pharaoh. They said, \"Indeed for us is a reward if we are the predominant.\"","tr":"Wajaa assaharatufirAAawna qaloo inna lana laajran in kunnanahnu alghalibeen","juz":9,"page":164},{"s":7,"a":114,"key":"7:114","ar":"قَالَ نَعَمْ وَإِنَّكُمْ لَمِنَ ٱلْمُقَرَّبِينَ","en":"He said, \"Yes, and, [moreover], you will be among those made near [to me].\"","tr":"Qala naAAam wa-innakum laminaalmuqarrabeen","juz":9,"page":164},{"s":7,"a":115,"key":"7:115","ar":"قَالُوا۟ يَـٰمُوسَىٰٓ إِمَّآ أَن تُلْقِىَ وَإِمَّآ أَن نَّكُونَ نَحْنُ ٱلْمُلْقِينَ","en":"They said, \"O Moses, either you throw [your staff], or we will be the ones to throw [first].\"","tr":"Qaloo ya moosa immaan tulqiya wa-imma an nakoona nahnu almulqeen","juz":9,"page":164},{"s":7,"a":116,"key":"7:116","ar":"قَالَ أَلْقُوا۟ ۖ فَلَمَّآ أَلْقَوْا۟ سَحَرُوٓا۟ أَعْيُنَ ٱلنَّاسِ وَٱسْتَرْهَبُوهُمْ وَجَآءُو بِسِحْرٍ عَظِيمٍ","en":"He said, \"Throw,\" and when they threw, they bewitched the eyes of the people and struck terror into them, and they presented a great [feat of] magic.1","tr":"Qala alqoo falamma alqaw saharooaAAyuna annasi wastarhaboohum wajaoobisihrin AAatheem","juz":9,"page":164},{"s":7,"a":117,"key":"7:117","ar":"۞ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَلْقِ عَصَاكَ ۖ فَإِذَا هِىَ تَلْقَفُ مَا يَأْفِكُونَ","en":"And We inspired to Moses, \"Throw your staff,\" and at once it devoured what they were falsifying.","tr":"Waawhayna ila moosaan alqi AAasaka fa-itha hiya talqafu maya/fikoon","juz":9,"page":164},{"s":7,"a":118,"key":"7:118","ar":"فَوَقَعَ ٱلْحَقُّ وَبَطَلَ مَا كَانُوا۟ يَعْمَلُونَ","en":"So the truth was established, and abolished was what they were doing.","tr":"FawaqaAAa alhaqqu wabatala makanoo yaAAmaloon","juz":9,"page":164},{"s":7,"a":119,"key":"7:119","ar":"فَغُلِبُوا۟ هُنَالِكَ وَٱنقَلَبُوا۟ صَـٰغِرِينَ","en":"And they [i.e., Pharaoh and his people] were overcome right there and became debased.","tr":"Faghuliboo hunalika wanqalaboosaghireen","juz":9,"page":164},{"s":7,"a":120,"key":"7:120","ar":"وَأُلْقِىَ ٱلسَّحَرَةُ سَـٰجِدِينَ","en":"And the magicians fell down in prostration [to Allāh].","tr":"Waolqiya assaharatu sajideen","juz":9,"page":164},{"s":7,"a":121,"key":"7:121","ar":"قَالُوٓا۟ ءَامَنَّا بِرَبِّ ٱلْعَـٰلَمِينَ","en":"They said, \"We have believed in the Lord of the worlds,","tr":"Qaloo amanna birabbialAAalameen","juz":9,"page":165},{"s":7,"a":122,"key":"7:122","ar":"رَبِّ مُوسَىٰ وَهَـٰرُونَ","en":"The Lord of Moses and Aaron.\"","tr":"Rabbi moosa waharoon","juz":9,"page":165},{"s":7,"a":123,"key":"7:123","ar":"قَالَ فِرْعَوْنُ ءَامَنتُم بِهِۦ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّ هَـٰذَا لَمَكْرٌ مَّكَرْتُمُوهُ فِى ٱلْمَدِينَةِ لِتُخْرِجُوا۟ مِنْهَآ أَهْلَهَا ۖ فَسَوْفَ تَعْلَمُونَ","en":"Said Pharaoh, \"You believed in him1 before I gave you permission. Indeed, this is a conspiracy which you conspired in the city to expel therefrom its people. But you are going to know.","tr":"Qala firAAawnu amantum bihiqabla an athana lakum inna hatha lamakrunmakartumoohu fee almadeenati litukhrijoo minha ahlahafasawfa taAAlamoon","juz":9,"page":165},{"s":7,"a":124,"key":"7:124","ar":"لَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَـٰفٍ ثُمَّ لَأُصَلِّبَنَّكُمْ أَجْمَعِينَ","en":"I will surely cut off your hands and your feet on opposite sides; then I will surely crucify you all.\"","tr":"LaoqatiAAanna aydiyakum waarjulakummin khilafin thumma laosallibannakum ajmaAAeen","juz":9,"page":165},{"s":7,"a":125,"key":"7:125","ar":"قَالُوٓا۟ إِنَّآ إِلَىٰ رَبِّنَا مُنقَلِبُونَ","en":"They said, \"Indeed, to our Lord we will return.","tr":"Qaloo inna ila rabbinamunqaliboon","juz":9,"page":165},{"s":7,"a":126,"key":"7:126","ar":"وَمَا تَنقِمُ مِنَّآ إِلَّآ أَنْ ءَامَنَّا بِـَٔايَـٰتِ رَبِّنَا لَمَّا جَآءَتْنَا ۚ رَبَّنَآ أَفْرِغْ عَلَيْنَا صَبْرًا وَتَوَفَّنَا مُسْلِمِينَ","en":"And you do not resent us except because we believed in the signs of our Lord when they came to us. Our Lord, pour upon us patience1 and let us die as Muslims [in submission to You].\"","tr":"Wama tanqimu minna illaan amanna bi-ayati rabbinalamma jaatna rabbana afrigh AAalaynasabran watawaffana muslimeen","juz":9,"page":165},{"s":7,"a":127,"key":"7:127","ar":"وَقَالَ ٱلْمَلَأُ مِن قَوْمِ فِرْعَوْنَ أَتَذَرُ مُوسَىٰ وَقَوْمَهُۥ لِيُفْسِدُوا۟ فِى ٱلْأَرْضِ وَيَذَرَكَ وَءَالِهَتَكَ ۚ قَالَ سَنُقَتِّلُ أَبْنَآءَهُمْ وَنَسْتَحْىِۦ نِسَآءَهُمْ وَإِنَّا فَوْقَهُمْ قَـٰهِرُونَ","en":"And the eminent among the people of Pharaoh said, \"Will you leave Moses and his people to cause corruption in the land and abandon you and your gods?\" [Pharaoh] said, \"We will kill their sons and keep their women alive; and indeed, we are subjugators over them.\"","tr":"Waqala almalao min qawmi firAAawnaatatharu moosa waqawmahu liyufsidoo fee al-ardiwayatharaka waalihataka qala sanuqattilu abnaahumwanastahyee nisaahum wa-inna fawqahum qahiroon","juz":9,"page":165},{"s":7,"a":128,"key":"7:128","ar":"قَالَ مُوسَىٰ لِقَوْمِهِ ٱسْتَعِينُوا۟ بِٱللَّهِ وَٱصْبِرُوٓا۟ ۖ إِنَّ ٱلْأَرْضَ لِلَّهِ يُورِثُهَا مَن يَشَآءُ مِنْ عِبَادِهِۦ ۖ وَٱلْعَـٰقِبَةُ لِلْمُتَّقِينَ","en":"Said Moses to his people, \"Seek help through Allāh and be patient. Indeed, the earth belongs to Allāh. He causes to inherit it whom He wills of His servants. And the [best] outcome is for the righteous.\"","tr":"Qala moosa liqawmihiistaAAeenoo billahi wasbiroo innaal-arda lillahi yoorithuha man yashaomin AAibadihi walAAaqibatu lilmuttaqeen","juz":9,"page":165},{"s":7,"a":129,"key":"7:129","ar":"قَالُوٓا۟ أُوذِينَا مِن قَبْلِ أَن تَأْتِيَنَا وَمِنۢ بَعْدِ مَا جِئْتَنَا ۚ قَالَ عَسَىٰ رَبُّكُمْ أَن يُهْلِكَ عَدُوَّكُمْ وَيَسْتَخْلِفَكُمْ فِى ٱلْأَرْضِ فَيَنظُرَ كَيْفَ تَعْمَلُونَ","en":"They said, \"We have been harmed before you came to us and after you have come to us.\" He said, \"Perhaps your Lord will destroy your enemy and grant you succession in the land and see how you will do.\"","tr":"Qaloo ootheena minqabli an ta/tiyana wamin baAAdi ma ji/tana qalaAAasa rabbukum an yuhlika AAaduwwakum wayastakhlifakum feeal-ardi fayanthura kayfa taAAmaloon","juz":9,"page":165},{"s":7,"a":130,"key":"7:130","ar":"وَلَقَدْ أَخَذْنَآ ءَالَ فِرْعَوْنَ بِٱلسِّنِينَ وَنَقْصٍ مِّنَ ٱلثَّمَرَٰتِ لَعَلَّهُمْ يَذَّكَّرُونَ","en":"And We certainly seized1 the people of Pharaoh with years of famine and a deficiency in fruits that perhaps they would be reminded.","tr":"Walaqad akhathna alafirAAawna bissineena wanaqsin mina aththamaratilaAAallahum yaththakkaroon","juz":9,"page":165},{"s":7,"a":131,"key":"7:131","ar":"فَإِذَا جَآءَتْهُمُ ٱلْحَسَنَةُ قَالُوا۟ لَنَا هَـٰذِهِۦ ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌ يَطَّيَّرُوا۟ بِمُوسَىٰ وَمَن مَّعَهُۥٓ ۗ أَلَآ إِنَّمَا طَـٰٓئِرُهُمْ عِندَ ٱللَّهِ وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ","en":"But when good [i.e., provision] came to them, they said, \"This is ours [by right].\" And if a bad [condition] struck them, they saw an evil omen in Moses and those with him. Unquestionably, their fortune is with Allāh, but most of them do not know.","tr":"Fa-itha jaat-humu alhasanatuqaloo lana hathihi wa-in tusibhumsayyi-atun yattayyaroo bimoosa waman maAAahu alainnama ta-iruhum AAinda Allahi walakinnaaktharahum la yaAAlamoon","juz":9,"page":166},{"s":7,"a":132,"key":"7:132","ar":"وَقَالُوا۟ مَهْمَا تَأْتِنَا بِهِۦ مِنْ ءَايَةٍ لِّتَسْحَرَنَا بِهَا فَمَا نَحْنُ لَكَ بِمُؤْمِنِينَ","en":"And they said, \"No matter what sign you bring us with which to bewitch us, we will not be believers in you.\"","tr":"Waqaloo mahma ta/tinabihi min ayatin litasharana biha famanahnu laka bimu/mineen","juz":9,"page":166},{"s":7,"a":133,"key":"7:133","ar":"فَأَرْسَلْنَا عَلَيْهِمُ ٱلطُّوفَانَ وَٱلْجَرَادَ وَٱلْقُمَّلَ وَٱلضَّفَادِعَ وَٱلدَّمَ ءَايَـٰتٍ مُّفَصَّلَـٰتٍ فَٱسْتَكْبَرُوا۟ وَكَانُوا۟ قَوْمًا مُّجْرِمِينَ","en":"So We sent upon them the flood and locusts and lice and frogs and blood as distinct signs, but they were arrogant and were a criminal people.","tr":"Faarsalna AAalayhimu attoofanawaljarada walqummala waddafadiAAawaddama ayatin mufassalatinfastakbaroo wakanoo qawman mujrimeen","juz":9,"page":166},{"s":7,"a":134,"key":"7:134","ar":"وَلَمَّا وَقَعَ عَلَيْهِمُ ٱلرِّجْزُ قَالُوا۟ يَـٰمُوسَى ٱدْعُ لَنَا رَبَّكَ بِمَا عَهِدَ عِندَكَ ۖ لَئِن كَشَفْتَ عَنَّا ٱلرِّجْزَ لَنُؤْمِنَنَّ لَكَ وَلَنُرْسِلَنَّ مَعَكَ بَنِىٓ إِسْرَٰٓءِيلَ","en":"And when the punishment descended upon them, they said, \"O Moses, invoke for us your Lord by what He has promised you. If you [can] remove the punishment from us, we will surely believe you, and we will send with you the Children of Israel.\"","tr":"Walamma waqaAAa AAalayhimu arrijzuqaloo ya moosa odAAu lana rabbaka bimaAAahida AAindaka la-in kashafta AAanna arrijzalanu/minanna laka walanursilanna maAAaka banee isra-eel","juz":9,"page":166},{"s":7,"a":135,"key":"7:135","ar":"فَلَمَّا كَشَفْنَا عَنْهُمُ ٱلرِّجْزَ إِلَىٰٓ أَجَلٍ هُم بَـٰلِغُوهُ إِذَا هُمْ يَنكُثُونَ","en":"But when We removed the punishment from them until a term which they were to reach,1 then at once they broke their word.","tr":"Falamma kashafna AAanhumu arrijzaila ajalin hum balighoohu itha humyankuthoon","juz":9,"page":166},{"s":7,"a":136,"key":"7:136","ar":"فَٱنتَقَمْنَا مِنْهُمْ فَأَغْرَقْنَـٰهُمْ فِى ٱلْيَمِّ بِأَنَّهُمْ كَذَّبُوا۟ بِـَٔايَـٰتِنَا وَكَانُوا۟ عَنْهَا غَـٰفِلِينَ","en":"So We took retribution from them, and We drowned them in the sea because they denied Our signs and were heedless of them.","tr":"Fantaqamna minhum faaghraqnahumfee alyammi bi-annahum kaththaboo bi-ayatinawakanoo AAanha ghafileen","juz":9,"page":166},{"s":7,"a":137,"key":"7:137","ar":"وَأَوْرَثْنَا ٱلْقَوْمَ ٱلَّذِينَ كَانُوا۟ يُسْتَضْعَفُونَ مَشَـٰرِقَ ٱلْأَرْضِ وَمَغَـٰرِبَهَا ٱلَّتِى بَـٰرَكْنَا فِيهَا ۖ وَتَمَّتْ كَلِمَتُ رَبِّكَ ٱلْحُسْنَىٰ عَلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ بِمَا صَبَرُوا۟ ۖ وَدَمَّرْنَا مَا كَانَ يَصْنَعُ فِرْعَوْنُ وَقَوْمُهُۥ وَمَا كَانُوا۟ يَعْرِشُونَ","en":"And We caused the people who had been oppressed to inherit the eastern regions of the land and the western ones, which We had blessed. And the good word [i.e., decree] of your Lord was fulfilled for the Children of Israel because of what they had patiently endured. And We destroyed [all] that Pharaoh and his people were producing and what they had been building.","tr":"Waawrathna alqawma allatheenakanoo yustadAAafoona mashariqa al-ardiwamagharibaha allatee barakna feehawatammat kalimatu rabbika alhusna AAalabanee isra-eela bima sabaroo wadammarnama kana yasnaAAu firAAawnu waqawmuhu wamakanoo yaAArishoon","juz":9,"page":166},{"s":7,"a":138,"key":"7:138","ar":"وَجَـٰوَزْنَا بِبَنِىٓ إِسْرَٰٓءِيلَ ٱلْبَحْرَ فَأَتَوْا۟ عَلَىٰ قَوْمٍ يَعْكُفُونَ عَلَىٰٓ أَصْنَامٍ لَّهُمْ ۚ قَالُوا۟ يَـٰمُوسَى ٱجْعَل لَّنَآ إِلَـٰهًا كَمَا لَهُمْ ءَالِهَةٌ ۚ قَالَ إِنَّكُمْ قَوْمٌ تَجْهَلُونَ","en":"And We took the Children of Israel across the sea; then they came upon a people intent in devotion to [some] idols of theirs. They [the Children of Israel] said, \"O Moses, make for us a god just as they have gods.\" He said, \"Indeed, you are a people behaving ignorantly.","tr":"Wajawazna bibanee isra-eelaalbahra faataw AAala qawmin yaAAkufoona AAalaasnamin lahum qaloo ya moosaijAAal lana ilahan kama lahum alihatunqala innakum qawmun tajhaloon","juz":9,"page":167},{"s":7,"a":139,"key":"7:139","ar":"إِنَّ هَـٰٓؤُلَآءِ مُتَبَّرٌ مَّا هُمْ فِيهِ وَبَـٰطِلٌ مَّا كَانُوا۟ يَعْمَلُونَ","en":"Indeed, those [worshippers] - destroyed is that in which they are [engaged], and worthless is whatever they were doing.\"","tr":"Inna haola-i mutabbarun mahum feehi wabatilun ma kanoo yaAAmaloon","juz":9,"page":167},{"s":7,"a":140,"key":"7:140","ar":"قَالَ أَغَيْرَ ٱللَّهِ أَبْغِيكُمْ إِلَـٰهًا وَهُوَ فَضَّلَكُمْ عَلَى ٱلْعَـٰلَمِينَ","en":"He said, \"Is it other than Allāh I should desire for you as a god1 while He has preferred you over the worlds?\"","tr":"Qala aghayra Allahi abgheekumilahan wahuwa faddalakum AAala alAAalameen","juz":9,"page":167},{"s":7,"a":141,"key":"7:141","ar":"وَإِذْ أَنجَيْنَـٰكُم مِّنْ ءَالِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ٱلْعَذَابِ ۖ يُقَتِّلُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْ ۚ وَفِى ذَٰلِكُم بَلَآءٌ مِّن رَّبِّكُمْ عَظِيمٌ","en":"And [recall, O Children of Israel], when We saved you from the people of Pharaoh, [who were] afflicting you with the worst torment - killing your sons and keeping your women alive. And in that was a great trial from your Lord.","tr":"Wa-ith anjaynakum min alifirAAawna yasoomoonakum soo-a alAAathabi yuqattiloona abnaakumwayastahyoona nisaakum wafee thalikum balaonmin rabbikum AAatheem","juz":9,"page":167},{"s":7,"a":142,"key":"7:142","ar":"۞ وَوَٰعَدْنَا مُوسَىٰ ثَلَـٰثِينَ لَيْلَةً وَأَتْمَمْنَـٰهَا بِعَشْرٍ فَتَمَّ مِيقَـٰتُ رَبِّهِۦٓ أَرْبَعِينَ لَيْلَةً ۚ وَقَالَ مُوسَىٰ لِأَخِيهِ هَـٰرُونَ ٱخْلُفْنِى فِى قَوْمِى وَأَصْلِحْ وَلَا تَتَّبِعْ سَبِيلَ ٱلْمُفْسِدِينَ","en":"And We made an appointment with Moses for thirty nights and perfected them by [the addition of] ten; so the term of his Lord was completed as forty nights. And Moses said to his brother Aaron, \"Take my place among my people, do right [by them],1 and do not follow the way of the corrupters.\"","tr":"WawaAAadna moosa thalatheenalaylatan waatmamnaha biAAashrin fatamma meeqaturabbihi arbaAAeena laylatan waqala moosa li-akheehiharoona okhlufnee fee qawmee waaslih walatattabiAA sabeela almufsideen","juz":9,"page":167},{"s":7,"a":143,"key":"7:143","ar":"وَلَمَّا جَآءَ مُوسَىٰ لِمِيقَـٰتِنَا وَكَلَّمَهُۥ رَبُّهُۥ قَالَ رَبِّ أَرِنِىٓ أَنظُرْ إِلَيْكَ ۚ قَالَ لَن تَرَىٰنِى وَلَـٰكِنِ ٱنظُرْ إِلَى ٱلْجَبَلِ فَإِنِ ٱسْتَقَرَّ مَكَانَهُۥ فَسَوْفَ تَرَىٰنِى ۚ فَلَمَّا تَجَلَّىٰ رَبُّهُۥ لِلْجَبَلِ جَعَلَهُۥ دَكًّا وَخَرَّ مُوسَىٰ صَعِقًا ۚ فَلَمَّآ أَفَاقَ قَالَ سُبْحَـٰنَكَ تُبْتُ إِلَيْكَ وَأَنَا۠ أَوَّلُ ٱلْمُؤْمِنِينَ","en":"And when Moses arrived at Our appointed time and his Lord spoke to him, he said, \"My Lord, show me [Yourself] that I may look at You.\" [Allāh] said, \"You will not see Me,1 but look at the mountain; if it should remain in place, then you will see Me.\" But when his Lord appeared to the mountain, He rendered it level,2 and Moses fell unconscious. And when he awoke, he said, \"Exalted are You! I have repented to You, and I am the first [among my people] of the believers.\"3","tr":"Walamma jaa moosalimeeqatina wakallamahu rabbuhu qala rabbiarinee anthur ilayka qala lan taraneewalakini onthur ila aljabali fa-iniistaqarra makanahu fasawfa taranee falammatajalla rabbuhu liljabali jaAAalahu dakkan wakharra moosasaAAiqan falamma afaqa qala subhanakatubtu ilayka waana awwalu almu/mineen","juz":9,"page":167},{"s":7,"a":144,"key":"7:144","ar":"قَالَ يَـٰمُوسَىٰٓ إِنِّى ٱصْطَفَيْتُكَ عَلَى ٱلنَّاسِ بِرِسَـٰلَـٰتِى وَبِكَلَـٰمِى فَخُذْ مَآ ءَاتَيْتُكَ وَكُن مِّنَ ٱلشَّـٰكِرِينَ","en":"[Allāh] said, \"O Moses, I have chosen you over the people with My messages and My words [to you]. So take what I have given you and be among the grateful.\"","tr":"Qala ya moosa innee istafaytukaAAala annasi birisalateewabikalamee fakhuth ma ataytuka wakunmina ashshakireen","juz":9,"page":168},{"s":7,"a":145,"key":"7:145","ar":"وَكَتَبْنَا لَهُۥ فِى ٱلْأَلْوَاحِ مِن كُلِّ شَىْءٍ مَّوْعِظَةً وَتَفْصِيلًا لِّكُلِّ شَىْءٍ فَخُذْهَا بِقُوَّةٍ وَأْمُرْ قَوْمَكَ يَأْخُذُوا۟ بِأَحْسَنِهَا ۚ سَأُو۟رِيكُمْ دَارَ ٱلْفَـٰسِقِينَ","en":"And We wrote for him on the tablets [something] of all things - instruction and explanation for all things, [saying], \"Take them with determination and order your people to take the best of it. I will show you the home of the defiantly disobedient.\"1","tr":"Wakatabna lahu fee al-alwahimin kulli shay-in mawAAithatan watafseelanlikulli shay-in fakhuthha biquwwatin wa/mur qawmakaya/khuthoo bi-ahsaniha saoreekum daraalfasiqeen","juz":9,"page":168},{"s":7,"a":146,"key":"7:146","ar":"سَأَصْرِفُ عَنْ ءَايَـٰتِىَ ٱلَّذِينَ يَتَكَبَّرُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَإِن يَرَوْا۟ كُلَّ ءَايَةٍ لَّا يُؤْمِنُوا۟ بِهَا وَإِن يَرَوْا۟ سَبِيلَ ٱلرُّشْدِ لَا يَتَّخِذُوهُ سَبِيلًا وَإِن يَرَوْا۟ سَبِيلَ ٱلْغَىِّ يَتَّخِذُوهُ سَبِيلًا ۚ ذَٰلِكَ بِأَنَّهُمْ كَذَّبُوا۟ بِـَٔايَـٰتِنَا وَكَانُوا۟ عَنْهَا غَـٰفِلِينَ","en":"I will turn away from My signs those who are arrogant upon the earth without right; and if they should see every sign, they will not believe in it. And if they see the way of consciousness,1 they will not adopt it as a way; but if they see the way of error, they will adopt it as a way. That is because they have denied Our signs and they were heedless of them.","tr":"Saasrifu AAan ayatiyaallatheena yatakabbaroona fee al-ardi bighayri alhaqqiwa-in yaraw kulla ayatin la yu/minoo bihawa-in yaraw sabeela arrushdi la yattakhithoohusabeelan wa-in yaraw sabeela alghayyi yattakhithoohusabeelan thalika bi-annahum kaththaboo bi-ayatinawakanoo AAanha ghafileen","juz":9,"page":168},{"s":7,"a":147,"key":"7:147","ar":"وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا وَلِقَآءِ ٱلْـَٔاخِرَةِ حَبِطَتْ أَعْمَـٰلُهُمْ ۚ هَلْ يُجْزَوْنَ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ","en":"Those who denied Our signs and the meeting of the Hereafter - their deeds have become worthless. Are they recompensed except for what they used to do?","tr":"Wallatheena kaththaboobi-ayatina waliqa-i al-akhiratihabitat aAAmaluhum hal yujzawna illama kanoo yaAAmaloon","juz":9,"page":168},{"s":7,"a":148,"key":"7:148","ar":"وَٱتَّخَذَ قَوْمُ مُوسَىٰ مِنۢ بَعْدِهِۦ مِنْ حُلِيِّهِمْ عِجْلًا جَسَدًا لَّهُۥ خُوَارٌ ۚ أَلَمْ يَرَوْا۟ أَنَّهُۥ لَا يُكَلِّمُهُمْ وَلَا يَهْدِيهِمْ سَبِيلًا ۘ ٱتَّخَذُوهُ وَكَانُوا۟ ظَـٰلِمِينَ","en":"And the people of Moses made, after [his departure], from their ornaments a calf - an image having a lowing sound. Did they not see that it could neither speak to them nor guide them to a way? They took it [for worship], and they were wrongdoers.","tr":"Wattakhatha qawmu moosamin baAAdihi min huliyyihim AAijlan jasadan lahu khuwarunalam yaraw annahu la yukallimuhum wala yahdeehimsabeelan ittakhathoohu wakanoo thalimeen","juz":9,"page":168},{"s":7,"a":149,"key":"7:149","ar":"وَلَمَّا سُقِطَ فِىٓ أَيْدِيهِمْ وَرَأَوْا۟ أَنَّهُمْ قَدْ ضَلُّوا۟ قَالُوا۟ لَئِن لَّمْ يَرْحَمْنَا رَبُّنَا وَيَغْفِرْ لَنَا لَنَكُونَنَّ مِنَ ٱلْخَـٰسِرِينَ","en":"And when regret overcame them1 and they saw that they had gone astray, they said, \"If our Lord does not have mercy upon us and forgive us, we will surely be among the losers.\"","tr":"Walamma suqita fee aydeehimwaraaw annahum qad dalloo qaloo la-in lam yarhamnarabbuna wayaghfir lana lanakoonanna mina alkhasireen","juz":9,"page":168},{"s":7,"a":150,"key":"7:150","ar":"وَلَمَّا رَجَعَ مُوسَىٰٓ إِلَىٰ قَوْمِهِۦ غَضْبَـٰنَ أَسِفًا قَالَ بِئْسَمَا خَلَفْتُمُونِى مِنۢ بَعْدِىٓ ۖ أَعَجِلْتُمْ أَمْرَ رَبِّكُمْ ۖ وَأَلْقَى ٱلْأَلْوَاحَ وَأَخَذَ بِرَأْسِ أَخِيهِ يَجُرُّهُۥٓ إِلَيْهِ ۚ قَالَ ٱبْنَ أُمَّ إِنَّ ٱلْقَوْمَ ٱسْتَضْعَفُونِى وَكَادُوا۟ يَقْتُلُونَنِى فَلَا تُشْمِتْ بِىَ ٱلْأَعْدَآءَ وَلَا تَجْعَلْنِى مَعَ ٱلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"And when Moses returned to his people, angry and grieved, he said, \"How wretched is that by which you have replaced me after [my departure]. Were you impatient over the matter of your Lord?\" And he threw down the tablets and seized his brother by [the hair of] his head, pulling him toward him. [Aaron] said, \"O son of my mother, indeed the people overpowered me and were about to kill me, so let not the enemies rejoice over me1 and do not place me among the wrongdoing people.\"","tr":"Walamma rajaAAa moosa ilaqawmihi ghadbana asifan qala bi/samakhalaftumoonee min baAAdee aAAajiltum amra rabbikum waalqa al-alwahawaakhatha bira/si akheehi yajurruhu ilayhi qalaibna omma inna alqawma istadAAafoonee wakadooyaqtuloonanee fala tushmit biya al-aAAdaa walatajAAalnee maAAa alqawmi aththalimeen","juz":9,"page":169},{"s":7,"a":151,"key":"7:151","ar":"قَالَ رَبِّ ٱغْفِرْ لِى وَلِأَخِى وَأَدْخِلْنَا فِى رَحْمَتِكَ ۖ وَأَنتَ أَرْحَمُ ٱلرَّٰحِمِينَ","en":"[Moses] said, \"My Lord, forgive me and my brother and admit us into Your mercy, for You are the most merciful of the merciful.\"","tr":"Qala rabbi ighfir lee wali-akheewaadkhilna fee rahmatika waanta arhamu arrahimeen","juz":9,"page":169},{"s":7,"a":152,"key":"7:152","ar":"إِنَّ ٱلَّذِينَ ٱتَّخَذُوا۟ ٱلْعِجْلَ سَيَنَالُهُمْ غَضَبٌ مِّن رَّبِّهِمْ وَذِلَّةٌ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُفْتَرِينَ","en":"Indeed, those who took the calf [for worship] will obtain anger from their Lord and humiliation in the life of this world, and thus do We recompense the inventors [of falsehood].","tr":"Inna allatheena ittakhathooalAAijla sayanaluhum ghadabun min rabbihim wathillatunfee alhayati addunya wakathalikanajzee almuftareen","juz":9,"page":169},{"s":7,"a":153,"key":"7:153","ar":"وَٱلَّذِينَ عَمِلُوا۟ ٱلسَّيِّـَٔاتِ ثُمَّ تَابُوا۟ مِنۢ بَعْدِهَا وَءَامَنُوٓا۟ إِنَّ رَبَّكَ مِنۢ بَعْدِهَا لَغَفُورٌ رَّحِيمٌ","en":"But those who committed misdeeds and then repented after them and believed - indeed your Lord, thereafter, is Forgiving and Merciful.","tr":"Wallatheena AAamiloo assayyi-atithumma taboo min baAAdiha waamanoo innarabbaka min baAAdiha laghafoorun raheem","juz":9,"page":169},{"s":7,"a":154,"key":"7:154","ar":"وَلَمَّا سَكَتَ عَن مُّوسَى ٱلْغَضَبُ أَخَذَ ٱلْأَلْوَاحَ ۖ وَفِى نُسْخَتِهَا هُدًى وَرَحْمَةٌ لِّلَّذِينَ هُمْ لِرَبِّهِمْ يَرْهَبُونَ","en":"And when the anger subsided in Moses, he took up the tablets; and in their inscription was guidance and mercy for those who are fearful of their Lord.","tr":"Walamma sakata AAan moosaalghadabu akhatha al-alwaha wafee nuskhatihahudan warahmatun lillatheena hum lirabbihimyarhaboon","juz":9,"page":169},{"s":7,"a":155,"key":"7:155","ar":"وَٱخْتَارَ مُوسَىٰ قَوْمَهُۥ سَبْعِينَ رَجُلًا لِّمِيقَـٰتِنَا ۖ فَلَمَّآ أَخَذَتْهُمُ ٱلرَّجْفَةُ قَالَ رَبِّ لَوْ شِئْتَ أَهْلَكْتَهُم مِّن قَبْلُ وَإِيَّـٰىَ ۖ أَتُهْلِكُنَا بِمَا فَعَلَ ٱلسُّفَهَآءُ مِنَّآ ۖ إِنْ هِىَ إِلَّا فِتْنَتُكَ تُضِلُّ بِهَا مَن تَشَآءُ وَتَهْدِى مَن تَشَآءُ ۖ أَنتَ وَلِيُّنَا فَٱغْفِرْ لَنَا وَٱرْحَمْنَا ۖ وَأَنتَ خَيْرُ ٱلْغَـٰفِرِينَ","en":"And Moses chose from his people seventy men for Our appointment.1 And when the earthquake seized them,2 he said, \"My Lord, if You had willed, You could have destroyed them before and me [as well]. Would You destroy us for what the foolish among us have done? This is not but Your trial by which You send astray whom You will and guide whom You will. You are our Protector, so forgive us and have mercy upon us; and You are the best of forgivers.","tr":"Wakhtara moosaqawmahu sabAAeena rajulan limeeqatina falammaakhathat-humu arrajfatu qala rabbi lawshi/ta ahlaktahum min qablu wa-iyyaya atuhlikunabima faAAala assufahao minna in hiyailla fitnatuka tudillu biha man tashaowatahdee man tashao anta waliyyuna faghfirlana warhamna waanta khayru alghafireen","juz":9,"page":169},{"s":7,"a":156,"key":"7:156","ar":"۞ وَٱكْتُبْ لَنَا فِى هَـٰذِهِ ٱلدُّنْيَا حَسَنَةً وَفِى ٱلْـَٔاخِرَةِ إِنَّا هُدْنَآ إِلَيْكَ ۚ قَالَ عَذَابِىٓ أُصِيبُ بِهِۦ مَنْ أَشَآءُ ۖ وَرَحْمَتِى وَسِعَتْ كُلَّ شَىْءٍ ۚ فَسَأَكْتُبُهَا لِلَّذِينَ يَتَّقُونَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَٱلَّذِينَ هُم بِـَٔايَـٰتِنَا يُؤْمِنُونَ","en":"And decree for us in this world [that which is] good and [also] in the Hereafter; indeed, we have turned back to You.\" [Allāh] said, \"My punishment - I afflict with it whom I will, but My mercy encompasses all things.\" So I will decree it [especially] for those who fear Me and give zakāh and those who believe in Our verses-","tr":"Waktub lana fee hathihiaddunya hasanatan wafee al-akhiratiinna hudna ilayka qala AAathabee oseebubihi man ashao warahmatee wasiAAat kulla shay-infasaaktubuha lillatheena yattaqoona wayu/toona azzakatawallatheena hum bi-ayatinayu/minoon","juz":9,"page":170},{"s":7,"a":157,"key":"7:157","ar":"ٱلَّذِينَ يَتَّبِعُونَ ٱلرَّسُولَ ٱلنَّبِىَّ ٱلْأُمِّىَّ ٱلَّذِى يَجِدُونَهُۥ مَكْتُوبًا عِندَهُمْ فِى ٱلتَّوْرَىٰةِ وَٱلْإِنجِيلِ يَأْمُرُهُم بِٱلْمَعْرُوفِ وَيَنْهَىٰهُمْ عَنِ ٱلْمُنكَرِ وَيُحِلُّ لَهُمُ ٱلطَّيِّبَـٰتِ وَيُحَرِّمُ عَلَيْهِمُ ٱلْخَبَـٰٓئِثَ وَيَضَعُ عَنْهُمْ إِصْرَهُمْ وَٱلْأَغْلَـٰلَ ٱلَّتِى كَانَتْ عَلَيْهِمْ ۚ فَٱلَّذِينَ ءَامَنُوا۟ بِهِۦ وَعَزَّرُوهُ وَنَصَرُوهُ وَٱتَّبَعُوا۟ ٱلنُّورَ ٱلَّذِىٓ أُنزِلَ مَعَهُۥٓ ۙ أُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"Those who follow the Messenger, the unlettered prophet, whom they find written [i.e., described] in what they have of the Torah and the Gospel, who enjoins upon them what is right and prohibits them from what is wrong and makes lawful for them what is good and forbids them from what is evil and relieves them of their burden1 and the shackles which were upon them.2 So they who have believed in him, honored him, supported him and followed the light which was sent down with him - it is those who will be the successful.","tr":"Allatheena yattabiAAoona arrasoolaannabiyya al-ommiyya allathee yajidoonahumaktooban AAindahum fee attawrati wal-injeeliya/muruhum bilmaAAroofi wayanhahum AAani almunkariwayuhillu lahumu attayyibati wayuharrimuAAalayhimu alkhaba-itha wayadaAAu AAanhum israhumwal-aghlala allatee kanat AAalayhim fallatheenaamanoo bihi waAAazzaroohu wanasaroohu wattabaAAooannoora allathee onzila maAAahu ola-ikahumu almuflihoon","juz":9,"page":170},{"s":7,"a":158,"key":"7:158","ar":"قُلْ يَـٰٓأَيُّهَا ٱلنَّاسُ إِنِّى رَسُولُ ٱللَّهِ إِلَيْكُمْ جَمِيعًا ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ لَآ إِلَـٰهَ إِلَّا هُوَ يُحْىِۦ وَيُمِيتُ ۖ فَـَٔامِنُوا۟ بِٱللَّهِ وَرَسُولِهِ ٱلنَّبِىِّ ٱلْأُمِّىِّ ٱلَّذِى يُؤْمِنُ بِٱللَّهِ وَكَلِمَـٰتِهِۦ وَٱتَّبِعُوهُ لَعَلَّكُمْ تَهْتَدُونَ","en":"Say, [O Muḥammad], \"O mankind, indeed I am the Messenger of Allāh to you all, [from Him] to whom belongs the dominion of the heavens and the earth. There is no deity except Him; He gives life and causes death.\" So believe in Allāh and His Messenger, the unlettered prophet, who believes in Allāh and His words, and follow him that you may be guided.","tr":"Qul ya ayyuha annasuinnee rasoolu Allahi ilaykum jameeAAan allatheelahu mulku assamawati wal-ardila ilaha illa huwa yuhyee wayumeetufaaminoo billahi warasoolihi annabiyyial-ommiyyi allathee yu/minu billahi wakalimatihiwattabiAAoohu laAAallakum tahtadoon","juz":9,"page":170},{"s":7,"a":159,"key":"7:159","ar":"وَمِن قَوْمِ مُوسَىٰٓ أُمَّةٌ يَهْدُونَ بِٱلْحَقِّ وَبِهِۦ يَعْدِلُونَ","en":"And among the people of Moses is a community1 which guides by truth and by it establishes justice.","tr":"Wamin qawmi moosa ommatun yahdoonabilhaqqi wabihi yaAAdiloon","juz":9,"page":170},{"s":7,"a":160,"key":"7:160","ar":"وَقَطَّعْنَـٰهُمُ ٱثْنَتَىْ عَشْرَةَ أَسْبَاطًا أُمَمًا ۚ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ إِذِ ٱسْتَسْقَىٰهُ قَوْمُهُۥٓ أَنِ ٱضْرِب بِّعَصَاكَ ٱلْحَجَرَ ۖ فَٱنۢبَجَسَتْ مِنْهُ ٱثْنَتَا عَشْرَةَ عَيْنًا ۖ قَدْ عَلِمَ كُلُّ أُنَاسٍ مَّشْرَبَهُمْ ۚ وَظَلَّلْنَا عَلَيْهِمُ ٱلْغَمَـٰمَ وَأَنزَلْنَا عَلَيْهِمُ ٱلْمَنَّ وَٱلسَّلْوَىٰ ۖ كُلُوا۟ مِن طَيِّبَـٰتِ مَا رَزَقْنَـٰكُمْ ۚ وَمَا ظَلَمُونَا وَلَـٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ","en":"And We divided them into twelve descendant tribes1 [as distinct] nations. And We inspired to Moses when his people implored him for water, \"Strike with your staff the stone,\" and there gushed forth from it twelve springs. Every people [i.e., tribe] knew its watering place. And We shaded them with clouds and sent down upon them manna and quails, [saying], \"Eat from the good things with which We have provided you.\" And they wronged Us not, but they were [only] wronging themselves.","tr":"WaqattaAAnahumu ithnatayAAashrata asbatan omaman waawhayna ilamoosa ithi istasqahu qawmuhu ani idribbiAAasaka alhajara fanbajasat minhu ithnataAAashrata AAaynan qad AAalima kullu onasin mashrabahum wathallalnaAAalayhimu alghamama waanzalna AAalayhimu almannawassalwa kuloo min tayyibati marazaqnakum wama thalamoona walakinkanoo anfusahum yathlimoon","juz":9,"page":171},{"s":7,"a":161,"key":"7:161","ar":"وَإِذْ قِيلَ لَهُمُ ٱسْكُنُوا۟ هَـٰذِهِ ٱلْقَرْيَةَ وَكُلُوا۟ مِنْهَا حَيْثُ شِئْتُمْ وَقُولُوا۟ حِطَّةٌ وَٱدْخُلُوا۟ ٱلْبَابَ سُجَّدًا نَّغْفِرْ لَكُمْ خَطِيٓـَٔـٰتِكُمْ ۚ سَنَزِيدُ ٱلْمُحْسِنِينَ","en":"And [mention, O Muḥammad], when it was said to them, \"Dwell in this city [i.e., Jerusalem] and eat from it wherever you will and say, 'Relieve us of our burdens [i.e., sins],' and enter the gate bowing humbly; We will [then] forgive you your sins. We will increase the doers of good [in goodness and reward].\"","tr":"Wa-ith qeela lahumu oskunoo hathihialqaryata wakuloo minha haythu shi/tum waqooloo hittatunwadkhuloo albaba sujjadan naghfir lakum khatee-atikumsanazeedu almuhsineen","juz":9,"page":171},{"s":7,"a":162,"key":"7:162","ar":"فَبَدَّلَ ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ قَوْلًا غَيْرَ ٱلَّذِى قِيلَ لَهُمْ فَأَرْسَلْنَا عَلَيْهِمْ رِجْزًا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَظْلِمُونَ","en":"But those who wronged among them changed [the words] to a statement other than that which had been said to them. So We sent upon them a punishment from the sky for the wrong that they were doing.","tr":"Fabaddala allatheena thalamoominhum qawlan ghayra allathee qeela lahum faarsalnaAAalayhim rijzan mina assama-i bima kanooyathlimoon","juz":9,"page":171},{"s":7,"a":163,"key":"7:163","ar":"وَسْـَٔلْهُمْ عَنِ ٱلْقَرْيَةِ ٱلَّتِى كَانَتْ حَاضِرَةَ ٱلْبَحْرِ إِذْ يَعْدُونَ فِى ٱلسَّبْتِ إِذْ تَأْتِيهِمْ حِيتَانُهُمْ يَوْمَ سَبْتِهِمْ شُرَّعًا وَيَوْمَ لَا يَسْبِتُونَ ۙ لَا تَأْتِيهِمْ ۚ كَذَٰلِكَ نَبْلُوهُم بِمَا كَانُوا۟ يَفْسُقُونَ","en":"And ask them about the town that was by the sea - when they transgressed in [the matter of] the sabbath - when their fish came to them openly on their sabbath day, and the day they had no sabbath they did not come to them. Thus did We give them trial because they were defiantly disobedient.","tr":"Was-alhum AAani alqaryati allatee kanathadirata albahri ith yaAAdoona fee assabtiith ta/teehim heetanuhum yawma sabtihimshurraAAan wayawma la yasbitoona la ta/teehim kathalikanabloohum bima kanoo yafsuqoon","juz":9,"page":171},{"s":7,"a":164,"key":"7:164","ar":"وَإِذْ قَالَتْ أُمَّةٌ مِّنْهُمْ لِمَ تَعِظُونَ قَوْمًا ۙ ٱللَّهُ مُهْلِكُهُمْ أَوْ مُعَذِّبُهُمْ عَذَابًا شَدِيدًا ۖ قَالُوا۟ مَعْذِرَةً إِلَىٰ رَبِّكُمْ وَلَعَلَّهُمْ يَتَّقُونَ","en":"And when a community among them said, \"Why do you advise [or warn] a people whom Allāh is [about] to destroy or to punish with a severe punishment?\" they [the advisors] said, \"To be absolved before your Lord and perhaps they may fear Him.\"","tr":"Wa-ith qalat ommatun minhumlima taAAithoona qawman Allahu muhlikuhum awmuAAaththibuhum AAathaban shadeedan qaloomaAAthiratan ila rabbikum walaAAallahum yattaqoon","juz":9,"page":172},{"s":7,"a":165,"key":"7:165","ar":"فَلَمَّا نَسُوا۟ مَا ذُكِّرُوا۟ بِهِۦٓ أَنجَيْنَا ٱلَّذِينَ يَنْهَوْنَ عَنِ ٱلسُّوٓءِ وَأَخَذْنَا ٱلَّذِينَ ظَلَمُوا۟ بِعَذَابٍۭ بَـِٔيسٍۭ بِمَا كَانُوا۟ يَفْسُقُونَ","en":"And when they [i.e., those advised] forgot that by which they had been reminded, We saved those who had forbidden evil and seized those who wronged, with a wretched punishment, because they were defiantly disobeying.","tr":"Falamma nasoo ma thukkiroobihi anjayna allatheena yanhawna AAani assoo-iwaakhathna allatheena thalamoobiAAathabin ba-eesin bima kanoo yafsuqoon","juz":9,"page":172},{"s":7,"a":166,"key":"7:166","ar":"فَلَمَّا عَتَوْا۟ عَن مَّا نُهُوا۟ عَنْهُ قُلْنَا لَهُمْ كُونُوا۟ قِرَدَةً خَـٰسِـِٔينَ","en":"So when they were insolent about that which they had been forbidden, We said to them, \"Be apes, despised.\"","tr":"Falamma AAataw AAan ma nuhooAAanhu qulna lahum koonoo qiradatan khasi-een","juz":9,"page":172},{"s":7,"a":167,"key":"7:167","ar":"وَإِذْ تَأَذَّنَ رَبُّكَ لَيَبْعَثَنَّ عَلَيْهِمْ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ مَن يَسُومُهُمْ سُوٓءَ ٱلْعَذَابِ ۗ إِنَّ رَبَّكَ لَسَرِيعُ ٱلْعِقَابِ ۖ وَإِنَّهُۥ لَغَفُورٌ رَّحِيمٌ","en":"And [mention] when your Lord declared that He would surely [continue to] send upon them until the Day of Resurrection those who would afflict them with the worst torment. Indeed, your Lord is swift in penalty; but indeed, He is Forgiving and Merciful.","tr":"Wa-ith taaththana rabbukalayabAAathanna AAalayhim ila yawmi alqiyamati manyasoomuhum soo-a alAAathabi inna rabbaka lasareeAAu alAAiqabiwa-innahu laghafoorun raheem","juz":9,"page":172},{"s":7,"a":168,"key":"7:168","ar":"وَقَطَّعْنَـٰهُمْ فِى ٱلْأَرْضِ أُمَمًا ۖ مِّنْهُمُ ٱلصَّـٰلِحُونَ وَمِنْهُمْ دُونَ ذَٰلِكَ ۖ وَبَلَوْنَـٰهُم بِٱلْحَسَنَـٰتِ وَٱلسَّيِّـَٔاتِ لَعَلَّهُمْ يَرْجِعُونَ","en":"And We divided them throughout the earth into nations. Of them some were righteous, and of them some were otherwise. And We tested them with good [times] and bad that perhaps they would return [to obedience].","tr":"WaqattaAAnahum fee al-ardiomaman minhumu assalihoona waminhum doona thalikawabalawnahum bilhasanati wassayyi-atilaAAallahum yarjiAAoon","juz":9,"page":172},{"s":7,"a":169,"key":"7:169","ar":"فَخَلَفَ مِنۢ بَعْدِهِمْ خَلْفٌ وَرِثُوا۟ ٱلْكِتَـٰبَ يَأْخُذُونَ عَرَضَ هَـٰذَا ٱلْأَدْنَىٰ وَيَقُولُونَ سَيُغْفَرُ لَنَا وَإِن يَأْتِهِمْ عَرَضٌ مِّثْلُهُۥ يَأْخُذُوهُ ۚ أَلَمْ يُؤْخَذْ عَلَيْهِم مِّيثَـٰقُ ٱلْكِتَـٰبِ أَن لَّا يَقُولُوا۟ عَلَى ٱللَّهِ إِلَّا ٱلْحَقَّ وَدَرَسُوا۟ مَا فِيهِ ۗ وَٱلدَّارُ ٱلْـَٔاخِرَةُ خَيْرٌ لِّلَّذِينَ يَتَّقُونَ ۗ أَفَلَا تَعْقِلُونَ","en":"And there followed them successors who inherited the Scripture [while] taking the commodities1 of this lower life and saying, \"It will be forgiven for us.\" And if an offer like it2 comes to them, they will [again] take it. Was not the covenant of the Scripture [i.e., the Torah] taken from them that they would not say about Allāh except the truth, and they studied what was in it? And the home of the Hereafter is better for those who fear Allāh, so will you not use reason?","tr":"Fakhalafa min baAAdihim khalfun warithooalkitaba ya/khuthoona AAarada hathaal-adna wayaqooloona sayughfaru lana wa-in ya/tihimAAaradun mithluhu ya/khuthoohu alam yu/khathAAalayhim meethaqu alkitabi an la yaqoolooAAala Allahi illa alhaqqa wadarasoo mafeehi waddaru al-akhiratu khayrun lillatheenayattaqoona afala taAAqiloon","juz":9,"page":172},{"s":7,"a":170,"key":"7:170","ar":"وَٱلَّذِينَ يُمَسِّكُونَ بِٱلْكِتَـٰبِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ إِنَّا لَا نُضِيعُ أَجْرَ ٱلْمُصْلِحِينَ","en":"But those who hold fast to the Book [i.e., the Qur’ān] and establish prayer - indeed, We will not allow to be lost the reward of the reformers.","tr":"Wallatheena yumassikoona bilkitabiwaaqamoo assalata inna lanudeeAAu ajra almusliheen","juz":9,"page":172},{"s":7,"a":171,"key":"7:171","ar":"۞ وَإِذْ نَتَقْنَا ٱلْجَبَلَ فَوْقَهُمْ كَأَنَّهُۥ ظُلَّةٌ وَظَنُّوٓا۟ أَنَّهُۥ وَاقِعٌۢ بِهِمْ خُذُوا۟ مَآ ءَاتَيْنَـٰكُم بِقُوَّةٍ وَٱذْكُرُوا۟ مَا فِيهِ لَعَلَّكُمْ تَتَّقُونَ","en":"And [mention] when We raised the mountain above them as if it was a dark cloud and they were certain that it would fall upon them,1 [and Allāh said], \"Take what We have given you with determination and remember what is in it that you might fear Allāh.\"","tr":"Wa-ith nataqna aljabalafawqahum kaannahu thullatun wathannooannahu waqiAAun bihim khuthoo ma ataynakumbiquwwatin wathkuroo ma feehi laAAallakumtattaqoon","juz":9,"page":173},{"s":7,"a":172,"key":"7:172","ar":"وَإِذْ أَخَذَ رَبُّكَ مِنۢ بَنِىٓ ءَادَمَ مِن ظُهُورِهِمْ ذُرِّيَّتَهُمْ وَأَشْهَدَهُمْ عَلَىٰٓ أَنفُسِهِمْ أَلَسْتُ بِرَبِّكُمْ ۖ قَالُوا۟ بَلَىٰ ۛ شَهِدْنَآ ۛ أَن تَقُولُوا۟ يَوْمَ ٱلْقِيَـٰمَةِ إِنَّا كُنَّا عَنْ هَـٰذَا غَـٰفِلِينَ","en":"And [mention] when your Lord took from the children of Adam - from their loins - their descendants and made them testify of themselves, [saying to them], \"Am I not your Lord?\" They said, \"Yes, we have testified.\" [This] - lest you should say on the Day of Resurrection, \"Indeed, we were of this unaware.\"","tr":"Wa-ith akhatha rabbuka minbanee adama min thuhoorihim thurriyyatahumwaashhadahum AAala anfusihim alastu birabbikum qaloobala shahidna an taqooloo yawma alqiyamatiinna kunna AAan hatha ghafileen","juz":9,"page":173},{"s":7,"a":173,"key":"7:173","ar":"أَوْ تَقُولُوٓا۟ إِنَّمَآ أَشْرَكَ ءَابَآؤُنَا مِن قَبْلُ وَكُنَّا ذُرِّيَّةً مِّنۢ بَعْدِهِمْ ۖ أَفَتُهْلِكُنَا بِمَا فَعَلَ ٱلْمُبْطِلُونَ","en":"Or [lest] you say, \"It was only that our fathers associated [others in worship] with Allāh before, and we were but descendants after them. Then would You destroy us for what the falsifiers have done?\"","tr":"Aw taqooloo innama ashraka abaonamin qablu wakunna thurriyyatan min baAAdihimafatuhlikuna bima faAAala almubtiloon","juz":9,"page":173},{"s":7,"a":174,"key":"7:174","ar":"وَكَذَٰلِكَ نُفَصِّلُ ٱلْـَٔايَـٰتِ وَلَعَلَّهُمْ يَرْجِعُونَ","en":"And thus do We [explain in] detail the verses, and perhaps they will return.1","tr":"Wakathalika nufassilu al-ayatiwalaAAallahum yarjiAAoon","juz":9,"page":173},{"s":7,"a":175,"key":"7:175","ar":"وَٱتْلُ عَلَيْهِمْ نَبَأَ ٱلَّذِىٓ ءَاتَيْنَـٰهُ ءَايَـٰتِنَا فَٱنسَلَخَ مِنْهَا فَأَتْبَعَهُ ٱلشَّيْطَـٰنُ فَكَانَ مِنَ ٱلْغَاوِينَ","en":"And recite to them, [O Muḥammad], the news of him1 to whom We gave [knowledge of] Our signs, but he detached himself from them; so Satan pursued him, and he became of the deviators.2","tr":"Watlu AAalayhim nabaa allatheeataynahu ayatina fansalakhaminha faatbaAAahu ashshaytanu fakanamina alghaween","juz":9,"page":173},{"s":7,"a":176,"key":"7:176","ar":"وَلَوْ شِئْنَا لَرَفَعْنَـٰهُ بِهَا وَلَـٰكِنَّهُۥٓ أَخْلَدَ إِلَى ٱلْأَرْضِ وَٱتَّبَعَ هَوَىٰهُ ۚ فَمَثَلُهُۥ كَمَثَلِ ٱلْكَلْبِ إِن تَحْمِلْ عَلَيْهِ يَلْهَثْ أَوْ تَتْرُكْهُ يَلْهَث ۚ ذَّٰلِكَ مَثَلُ ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا ۚ فَٱقْصُصِ ٱلْقَصَصَ لَعَلَّهُمْ يَتَفَكَّرُونَ","en":"And if We had willed, We could have elevated him thereby,1 but he adhered [instead] to the earth2 and followed his own desire. So his example is like that of the dog: if you chase him, he pants, or if you leave him, he [still] pants. That is the example of the people who denied Our signs.3 So relate the stories that perhaps they will give thought.","tr":"Walaw shi/na larafaAAnahu bihawalakinnahu akhlada ila al-ardi wattabaAAahawahu famathaluhu kamathali alkalbi in tahmilAAalayhi yalhath aw tatruk-hu yalhath thalika mathalualqawmi allatheena kaththaboo bi-ayatinafaqsusi alqasasa laAAallahumyatafakkaroon","juz":9,"page":173},{"s":7,"a":177,"key":"7:177","ar":"سَآءَ مَثَلًا ٱلْقَوْمُ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا وَأَنفُسَهُمْ كَانُوا۟ يَظْلِمُونَ","en":"How evil an example [is that of] the people who denied Our signs and used to wrong themselves.","tr":"Saa mathalan alqawmu allatheenakaththaboo bi-ayatina waanfusahum kanooyathlimoon","juz":9,"page":173},{"s":7,"a":178,"key":"7:178","ar":"مَن يَهْدِ ٱللَّهُ فَهُوَ ٱلْمُهْتَدِى ۖ وَمَن يُضْلِلْ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْخَـٰسِرُونَ","en":"Whoever Allāh guides - he is the [rightly] guided; and whoever He sends astray1 - it is those who are the losers.","tr":"Man yahdi Allahu fahuwa almuhtadeewaman yudlil faola-ika humu alkhasiroon","juz":9,"page":173},{"s":7,"a":179,"key":"7:179","ar":"وَلَقَدْ ذَرَأْنَا لِجَهَنَّمَ كَثِيرًا مِّنَ ٱلْجِنِّ وَٱلْإِنسِ ۖ لَهُمْ قُلُوبٌ لَّا يَفْقَهُونَ بِهَا وَلَهُمْ أَعْيُنٌ لَّا يُبْصِرُونَ بِهَا وَلَهُمْ ءَاذَانٌ لَّا يَسْمَعُونَ بِهَآ ۚ أُو۟لَـٰٓئِكَ كَٱلْأَنْعَـٰمِ بَلْ هُمْ أَضَلُّ ۚ أُو۟لَـٰٓئِكَ هُمُ ٱلْغَـٰفِلُونَ","en":"And We have certainly created for Hell many of the jinn and mankind. They have hearts with which they do not understand, they have eyes with which they do not see, and they have ears with which they do not hear. Those are like livestock; rather, they are more astray.1 It is they who are the heedless.","tr":"Walaqad thara/na lijahannamakatheeran mina aljinni wal-insi lahum quloobun layafqahoona biha walahum aAAyunun la yubsiroonabiha walahum athanun la yasmaAAoona bihaola-ika kal-anAAami bal hum adalluola-ika humu alghafiloon","juz":9,"page":174},{"s":7,"a":180,"key":"7:180","ar":"وَلِلَّهِ ٱلْأَسْمَآءُ ٱلْحُسْنَىٰ فَٱدْعُوهُ بِهَا ۖ وَذَرُوا۟ ٱلَّذِينَ يُلْحِدُونَ فِىٓ أَسْمَـٰٓئِهِۦ ۚ سَيُجْزَوْنَ مَا كَانُوا۟ يَعْمَلُونَ","en":"And to Allāh belong the best names, so invoke Him by them. And leave [the company of] those who practice deviation concerning His names.1 They will be recompensed for what they have been doing.","tr":"Walillahi al-asmao alhusnafadAAoohu biha watharoo allatheenayulhidoona fee asma-ihi sayujzawna ma kanooyaAAmaloon","juz":9,"page":174},{"s":7,"a":181,"key":"7:181","ar":"وَمِمَّنْ خَلَقْنَآ أُمَّةٌ يَهْدُونَ بِٱلْحَقِّ وَبِهِۦ يَعْدِلُونَ","en":"And among those We created is a community1 which guides by truth and thereby establishes justice.","tr":"Wamimman khalaqna ommatun yahdoonabilhaqqi wabihi yaAAdiloon","juz":9,"page":174},{"s":7,"a":182,"key":"7:182","ar":"وَٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا سَنَسْتَدْرِجُهُم مِّنْ حَيْثُ لَا يَعْلَمُونَ","en":"But those who deny Our signs - We will progressively lead them [to destruction]1 from where they do not know.","tr":"Wallatheena kaththaboobi-ayatina sanastadrijuhum min haythula yaAAlamoon","juz":9,"page":174},{"s":7,"a":183,"key":"7:183","ar":"وَأُمْلِى لَهُمْ ۚ إِنَّ كَيْدِى مَتِينٌ","en":"And I will give them time. Indeed, My plan is firm.","tr":"Waomlee lahum inna kaydee mateen","juz":9,"page":174},{"s":7,"a":184,"key":"7:184","ar":"أَوَلَمْ يَتَفَكَّرُوا۟ ۗ مَا بِصَاحِبِهِم مِّن جِنَّةٍ ۚ إِنْ هُوَ إِلَّا نَذِيرٌ مُّبِينٌ","en":"Then do they not give thought? There is in their companion [i.e., Muḥammad (ﷺ)] no madness. He is not but a clear warner.","tr":"Awa lam yatafakkaroo ma bisahibihimmin jinnatin in huwa illa natheerun mubeen","juz":9,"page":174},{"s":7,"a":185,"key":"7:185","ar":"أَوَلَمْ يَنظُرُوا۟ فِى مَلَكُوتِ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا خَلَقَ ٱللَّهُ مِن شَىْءٍ وَأَنْ عَسَىٰٓ أَن يَكُونَ قَدِ ٱقْتَرَبَ أَجَلُهُمْ ۖ فَبِأَىِّ حَدِيثٍۭ بَعْدَهُۥ يُؤْمِنُونَ","en":"Do they not look into the realm of the heavens and the earth and everything that Allāh has created and [think] that perhaps their appointed time has come near? So in what statement [i.e., message] hereafter will they believe?","tr":"Awalam yanthuroo feemalakooti assamawati wal-ardiwama khalaqa Allahu min shay-in waan AAasaan yakoona qadi iqtaraba ajaluhum fabi-ayyi hadeethinbaAAdahu yu/minoon","juz":9,"page":174},{"s":7,"a":186,"key":"7:186","ar":"مَن يُضْلِلِ ٱللَّهُ فَلَا هَادِىَ لَهُۥ ۚ وَيَذَرُهُمْ فِى طُغْيَـٰنِهِمْ يَعْمَهُونَ","en":"Whoever Allāh sends astray - there is no guide for him. And He leaves them in their transgression, wandering blindly.","tr":"Man yudlili Allahu falahadiya lahu wayatharuhum fee tughyanihimyaAAmahoon","juz":9,"page":174},{"s":7,"a":187,"key":"7:187","ar":"يَسْـَٔلُونَكَ عَنِ ٱلسَّاعَةِ أَيَّانَ مُرْسَىٰهَا ۖ قُلْ إِنَّمَا عِلْمُهَا عِندَ رَبِّى ۖ لَا يُجَلِّيهَا لِوَقْتِهَآ إِلَّا هُوَ ۚ ثَقُلَتْ فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ لَا تَأْتِيكُمْ إِلَّا بَغْتَةً ۗ يَسْـَٔلُونَكَ كَأَنَّكَ حَفِىٌّ عَنْهَا ۖ قُلْ إِنَّمَا عِلْمُهَا عِندَ ٱللَّهِ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"They ask you, [O Muḥammad], about the Hour: when is its arrival?1 Say, \"Its knowledge is only with my Lord. None will reveal its time except Him. It lays heavily2 upon the heavens and the earth. It will not come upon you except unexpectedly.\" They ask you as if you are familiar with it. Say, \"Its knowledge is only with Allāh, but most of the people do not know.\"","tr":"Yas-aloonaka AAani assaAAatiayyana mursaha qul innama AAilmuhaAAinda rabbee la yujalleeha liwaqtiha illahuwa thaqulat fee assamawati wal-ardila ta/teekum illa baghtatan yas-aloonaka kaannaka hafiyyunAAanha qul innama AAilmuha AAinda Allahiwalakinna akthara annasi layaAAlamoon","juz":9,"page":174},{"s":7,"a":188,"key":"7:188","ar":"قُل لَّآ أَمْلِكُ لِنَفْسِى نَفْعًا وَلَا ضَرًّا إِلَّا مَا شَآءَ ٱللَّهُ ۚ وَلَوْ كُنتُ أَعْلَمُ ٱلْغَيْبَ لَٱسْتَكْثَرْتُ مِنَ ٱلْخَيْرِ وَمَا مَسَّنِىَ ٱلسُّوٓءُ ۚ إِنْ أَنَا۠ إِلَّا نَذِيرٌ وَبَشِيرٌ لِّقَوْمٍ يُؤْمِنُونَ","en":"Say, \"I hold not for myself [the power of] benefit or harm, except what Allāh has willed. And if I knew the unseen, I could have acquired much wealth, and no harm would have touched me. I am not except a warner and a bringer of good tidings to a people who believe.\"","tr":"Qul la amliku linafsee nafAAan waladarran illa ma shaa Allahuwalaw kuntu aAAlamu alghayba lastakthartu mina alkhayriwama massaniya assoo-o in ana illanatheerun wabasheerun liqawmin yu/minoon","juz":9,"page":175},{"s":7,"a":189,"key":"7:189","ar":"۞ هُوَ ٱلَّذِى خَلَقَكُم مِّن نَّفْسٍ وَٰحِدَةٍ وَجَعَلَ مِنْهَا زَوْجَهَا لِيَسْكُنَ إِلَيْهَا ۖ فَلَمَّا تَغَشَّىٰهَا حَمَلَتْ حَمْلًا خَفِيفًا فَمَرَّتْ بِهِۦ ۖ فَلَمَّآ أَثْقَلَت دَّعَوَا ٱللَّهَ رَبَّهُمَا لَئِنْ ءَاتَيْتَنَا صَـٰلِحًا لَّنَكُونَنَّ مِنَ ٱلشَّـٰكِرِينَ","en":"It is He who created you from one soul and created from it its mate that he1 might dwell in security with her. And when he [i.e., man] covers her,2 she carries a light burden [i.e., a pregnancy] and continues therein. And when it becomes heavy, they both invoke Allāh, their Lord, \"If You should give us a good3 [child], we will surely be among the grateful.\"","tr":"Huwa allathee khalaqakum min nafsinwahidatin wajaAAala minha zawjaha liyaskunailayha falamma taghashshaha hamalathamlan khafeefan famarrat bihi falamma athqalatdaAAawa Allaha rabbahuma la-in ataytanasalihan lanakoonanna mina ashshakireen","juz":9,"page":175},{"s":7,"a":190,"key":"7:190","ar":"فَلَمَّآ ءَاتَىٰهُمَا صَـٰلِحًا جَعَلَا لَهُۥ شُرَكَآءَ فِيمَآ ءَاتَىٰهُمَا ۚ فَتَعَـٰلَى ٱللَّهُ عَمَّا يُشْرِكُونَ","en":"But when He gives them a good [child], they1 ascribe partners to Him concerning that which He has given them. Exalted is Allāh above what they associate with Him.","tr":"Falamma atahumasalihan jaAAala lahu shurakaa feemaatahuma fataAAala AllahuAAamma yushrikoon","juz":9,"page":175},{"s":7,"a":191,"key":"7:191","ar":"أَيُشْرِكُونَ مَا لَا يَخْلُقُ شَيْـًٔا وَهُمْ يُخْلَقُونَ","en":"Do they associate with Him those who create nothing and they are [themselves] created?","tr":"Ayushrikoona ma la yakhluqushay-an wahum yukhlaqoon","juz":9,"page":175},{"s":7,"a":192,"key":"7:192","ar":"وَلَا يَسْتَطِيعُونَ لَهُمْ نَصْرًا وَلَآ أَنفُسَهُمْ يَنصُرُونَ","en":"And they [i.e., the false deities] are unable to [give] them help, nor can they help themselves.","tr":"Wala yastateeAAoona lahum nasranwala anfusahum yansuroon","juz":9,"page":175},{"s":7,"a":193,"key":"7:193","ar":"وَإِن تَدْعُوهُمْ إِلَى ٱلْهُدَىٰ لَا يَتَّبِعُوكُمْ ۚ سَوَآءٌ عَلَيْكُمْ أَدَعَوْتُمُوهُمْ أَمْ أَنتُمْ صَـٰمِتُونَ","en":"And if you [believers] invite them to guidance, they will not follow you. It is all the same for you whether you invite them or you are silent.","tr":"Wa-in tadAAoohum ila alhuda layattabiAAookum sawaon AAalaykum adaAAawtumoohum am antum samitoon","juz":9,"page":175},{"s":7,"a":194,"key":"7:194","ar":"إِنَّ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ عِبَادٌ أَمْثَالُكُمْ ۖ فَٱدْعُوهُمْ فَلْيَسْتَجِيبُوا۟ لَكُمْ إِن كُنتُمْ صَـٰدِقِينَ","en":"Indeed, those you [polytheists] call upon besides Allāh are servants [i.e., creations] like you. So call upon them and let them respond to you, if you should be truthful.","tr":"Inna allatheena tadAAoona min dooniAllahi AAibadun amthalukum fadAAoohumfalyastajeeboo lakum in kuntum sadiqeen","juz":9,"page":175},{"s":7,"a":195,"key":"7:195","ar":"أَلَهُمْ أَرْجُلٌ يَمْشُونَ بِهَآ ۖ أَمْ لَهُمْ أَيْدٍ يَبْطِشُونَ بِهَآ ۖ أَمْ لَهُمْ أَعْيُنٌ يُبْصِرُونَ بِهَآ ۖ أَمْ لَهُمْ ءَاذَانٌ يَسْمَعُونَ بِهَا ۗ قُلِ ٱدْعُوا۟ شُرَكَآءَكُمْ ثُمَّ كِيدُونِ فَلَا تُنظِرُونِ","en":"Do they have feet by which they walk? Or do they have hands by which they strike? Or do they have eyes by which they see? Or do they have ears by which they hear? Say, [O Muḥammad], \"Call your 'partners' and then conspire against me and give me no respite.","tr":"Alahum arjulun yamshoona biha amlahum aydin yabtishoona biha am lahum aAAyunun yubsiroonabiha am lahum athanun yasmaAAoona biha quliodAAoo shurakaakum thumma keedooni fala tunthiroon","juz":9,"page":175},{"s":7,"a":196,"key":"7:196","ar":"إِنَّ وَلِـِّۧىَ ٱللَّهُ ٱلَّذِى نَزَّلَ ٱلْكِتَـٰبَ ۖ وَهُوَ يَتَوَلَّى ٱلصَّـٰلِحِينَ","en":"Indeed, my protector is Allāh, who has sent down the Book; and He is an ally to the righteous.","tr":"Inna waliyyiya Allahu allatheenazzala alkitaba wahuwa yatawalla assaliheen","juz":9,"page":176},{"s":7,"a":197,"key":"7:197","ar":"وَٱلَّذِينَ تَدْعُونَ مِن دُونِهِۦ لَا يَسْتَطِيعُونَ نَصْرَكُمْ وَلَآ أَنفُسَهُمْ يَنصُرُونَ","en":"And those you call upon besides Him are unable to help you, nor can they help themselves.\"","tr":"Wallatheena tadAAoona mindoonihi la yastateeAAoona nasrakum walaanfusahum yansuroon","juz":9,"page":176},{"s":7,"a":198,"key":"7:198","ar":"وَإِن تَدْعُوهُمْ إِلَى ٱلْهُدَىٰ لَا يَسْمَعُوا۟ ۖ وَتَرَىٰهُمْ يَنظُرُونَ إِلَيْكَ وَهُمْ لَا يُبْصِرُونَ","en":"And if you invite them to guidance, they do not hear; and you see them looking at you while they do not see.","tr":"Wa-in tadAAoohum ila alhuda layasmaAAoo watarahum yanthuroona ilayka wahumla yubsiroon","juz":9,"page":176},{"s":7,"a":199,"key":"7:199","ar":"خُذِ ٱلْعَفْوَ وَأْمُرْ بِٱلْعُرْفِ وَأَعْرِضْ عَنِ ٱلْجَـٰهِلِينَ","en":"Take what is given freely,1 enjoin what is good, and turn away from the ignorant.","tr":"Khuthi alAAafwa wa/mur bilAAurfiwaaAArid AAani aljahileen","juz":9,"page":176},{"s":7,"a":200,"key":"7:200","ar":"وَإِمَّا يَنزَغَنَّكَ مِنَ ٱلشَّيْطَـٰنِ نَزْغٌ فَٱسْتَعِذْ بِٱللَّهِ ۚ إِنَّهُۥ سَمِيعٌ عَلِيمٌ","en":"And if an evil suggestion comes to you from Satan, then seek refuge in Allāh. Indeed, He is Hearing and Knowing.","tr":"Wa-imma yanzaghannaka mina ashshaytaninazghun fastaAAith billahi innahusameeAAun AAaleem","juz":9,"page":176},{"s":7,"a":201,"key":"7:201","ar":"إِنَّ ٱلَّذِينَ ٱتَّقَوْا۟ إِذَا مَسَّهُمْ طَـٰٓئِفٌ مِّنَ ٱلشَّيْطَـٰنِ تَذَكَّرُوا۟ فَإِذَا هُم مُّبْصِرُونَ","en":"Indeed, those who fear Allāh - when an impulse touches them from Satan, they remember [Him] and at once they have insight.","tr":"Inna allatheena ittaqaw ithamassahum ta-ifun mina ashshaytani tathakkaroofa-itha hum mubsiroon","juz":9,"page":176},{"s":7,"a":202,"key":"7:202","ar":"وَإِخْوَٰنُهُمْ يَمُدُّونَهُمْ فِى ٱلْغَىِّ ثُمَّ لَا يُقْصِرُونَ","en":"But their brothers1 - they [i.e., the devils] increase them in error; then they do not stop short.","tr":"Wa-ikhwanuhum yamuddoonahum feealghayyi thumma la yuqsiroon","juz":9,"page":176},{"s":7,"a":203,"key":"7:203","ar":"وَإِذَا لَمْ تَأْتِهِم بِـَٔايَةٍ قَالُوا۟ لَوْلَا ٱجْتَبَيْتَهَا ۚ قُلْ إِنَّمَآ أَتَّبِعُ مَا يُوحَىٰٓ إِلَىَّ مِن رَّبِّى ۚ هَـٰذَا بَصَآئِرُ مِن رَّبِّكُمْ وَهُدًى وَرَحْمَةٌ لِّقَوْمٍ يُؤْمِنُونَ","en":"And when you, [O Muḥammad], do not bring them a sign [i.e., miracle], they say, \"Why have you not contrived it?\" Say, \"I only follow what is revealed to me from my Lord. This [Qur’ān] is enlightenment from your Lord and guidance and mercy for a people who believe.\"","tr":"Wa-itha lam ta/tihim bi-ayatinqaloo lawla ijtabaytaha qul innamaattabiAAu ma yooha ilayya min rabbee hathabasa-iru min rabbikum wahudan warahmatun liqawminyu/minoon","juz":9,"page":176},{"s":7,"a":204,"key":"7:204","ar":"وَإِذَا قُرِئَ ٱلْقُرْءَانُ فَٱسْتَمِعُوا۟ لَهُۥ وَأَنصِتُوا۟ لَعَلَّكُمْ تُرْحَمُونَ","en":"So when the Qur’ān is recited, then listen to it and pay attention that you may receive mercy.","tr":"Wa-itha quri-a alqur-anu fastamiAAoolahu waansitoo laAAallakum turhamoon","juz":9,"page":176},{"s":7,"a":205,"key":"7:205","ar":"وَٱذْكُر رَّبَّكَ فِى نَفْسِكَ تَضَرُّعًا وَخِيفَةً وَدُونَ ٱلْجَهْرِ مِنَ ٱلْقَوْلِ بِٱلْغُدُوِّ وَٱلْـَٔاصَالِ وَلَا تَكُن مِّنَ ٱلْغَـٰفِلِينَ","en":"And remember your Lord within yourself in humility and in fear without being apparent in speech - in the mornings and the evenings. And do not be among the heedless.","tr":"Wathkur rabbaka fee nafsikatadarruAAan wakheefatan wadoona aljahri mina alqawli bilghuduwwiwal-asali wala takun mina alghafileen","juz":9,"page":176},{"s":7,"a":206,"key":"7:206","ar":"إِنَّ ٱلَّذِينَ عِندَ رَبِّكَ لَا يَسْتَكْبِرُونَ عَنْ عِبَادَتِهِۦ وَيُسَبِّحُونَهُۥ وَلَهُۥ يَسْجُدُونَ ۩","en":"Indeed, those who are near your Lord [i.e., the angels] are not prevented by arrogance from His worship, and they exalt Him, and to Him they prostrate.","tr":"Inna allatheena AAinda rabbika layastakbiroona AAan AAibadatihi wayusabbihoonahuwalahu yasjudoon","juz":9,"page":176},{"s":8,"a":1,"key":"8:1","ar":" يَسْـَٔلُونَكَ عَنِ ٱلْأَنفَالِ ۖ قُلِ ٱلْأَنفَالُ لِلَّهِ وَٱلرَّسُولِ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَأَصْلِحُوا۟ ذَاتَ بَيْنِكُمْ ۖ وَأَطِيعُوا۟ ٱللَّهَ وَرَسُولَهُۥٓ إِن كُنتُم مُّؤْمِنِينَ","en":"They ask you, [O Muḥammad], about the bounties [of war]. Say, \"The [decision concerning] bounties is for Allāh and the Messenger.\" So fear Allāh and amend that which is between you and obey Allāh and His Messenger, if you should be believers.","tr":"Yas-aloonaka AAani al-anfali qulial-anfalu lillahi warrasooli fattaqooAllaha waaslihoo thata baynikum waateeAAooAllaha warasoolahu in kuntum mu/mineen","juz":9,"page":177},{"s":8,"a":2,"key":"8:2","ar":"إِنَّمَا ٱلْمُؤْمِنُونَ ٱلَّذِينَ إِذَا ذُكِرَ ٱللَّهُ وَجِلَتْ قُلُوبُهُمْ وَإِذَا تُلِيَتْ عَلَيْهِمْ ءَايَـٰتُهُۥ زَادَتْهُمْ إِيمَـٰنًا وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ","en":"The believers are only those who, when Allāh is mentioned, their hearts become fearful, and when His verses are recited to them, it increases them in faith; and upon their Lord they rely -","tr":"Innama almu/minoona allatheenaitha thukira Allahu wajilat quloobuhum wa-ithatuliyat AAalayhim ayatuhu zadat-hum eemananwaAAala rabbihim yatawakkaloon","juz":9,"page":177},{"s":8,"a":3,"key":"8:3","ar":"ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَ","en":"The ones who establish prayer, and from what We have provided them, they spend.","tr":"Allatheena yuqeemoona assalatawamimma razaqnahum yunfiqoon","juz":9,"page":177},{"s":8,"a":4,"key":"8:4","ar":"أُو۟لَـٰٓئِكَ هُمُ ٱلْمُؤْمِنُونَ حَقًّا ۚ لَّهُمْ دَرَجَـٰتٌ عِندَ رَبِّهِمْ وَمَغْفِرَةٌ وَرِزْقٌ كَرِيمٌ","en":"Those are the believers, truly. For them are degrees [of high position] with their Lord and forgiveness and noble provision.","tr":"Ola-ika humu almu/minoona haqqanlahum darajatun AAinda rabbihim wamaghfiratun warizqunkareem","juz":9,"page":177},{"s":8,"a":5,"key":"8:5","ar":"كَمَآ أَخْرَجَكَ رَبُّكَ مِنۢ بَيْتِكَ بِٱلْحَقِّ وَإِنَّ فَرِيقًا مِّنَ ٱلْمُؤْمِنِينَ لَكَـٰرِهُونَ","en":"[It1 is] just as when your Lord brought you out of your home [for the battle of Badr] in truth, while indeed, a party among the believers were unwilling,","tr":"Kama akhrajaka rabbuka min baytika bilhaqqiwa-inna fareeqan mina almu/mineena lakarihoon","juz":9,"page":177},{"s":8,"a":6,"key":"8:6","ar":"يُجَـٰدِلُونَكَ فِى ٱلْحَقِّ بَعْدَ مَا تَبَيَّنَ كَأَنَّمَا يُسَاقُونَ إِلَى ٱلْمَوْتِ وَهُمْ يَنظُرُونَ","en":"Arguing with you concerning the truth after it had become clear, as if they were being driven toward death while they were looking on.","tr":"Yujadiloonaka fee alhaqqibaAAda ma tabayyana kaannama yusaqoona ilaalmawti wahum yanthuroon","juz":9,"page":177},{"s":8,"a":7,"key":"8:7","ar":"وَإِذْ يَعِدُكُمُ ٱللَّهُ إِحْدَى ٱلطَّآئِفَتَيْنِ أَنَّهَا لَكُمْ وَتَوَدُّونَ أَنَّ غَيْرَ ذَاتِ ٱلشَّوْكَةِ تَكُونُ لَكُمْ وَيُرِيدُ ٱللَّهُ أَن يُحِقَّ ٱلْحَقَّ بِكَلِمَـٰتِهِۦ وَيَقْطَعَ دَابِرَ ٱلْكَـٰفِرِينَ","en":"[Remember, O believers], when Allāh promised you one of the two groups1 - that it would be yours - and you wished that the unarmed one would be yours. But Allāh intended to establish the truth by His words and to eliminate the disbelievers","tr":"Wa-ith yaAAidukumu Allahu ihdaatta-ifatayni annaha lakum watawaddoonaanna ghayra thati ashshawkati takoonu lakumwayureedu Allahu an yuhiqqa alhaqqa bikalimatihiwayaqtaAAa dabira alkafireen","juz":9,"page":177},{"s":8,"a":8,"key":"8:8","ar":"لِيُحِقَّ ٱلْحَقَّ وَيُبْطِلَ ٱلْبَـٰطِلَ وَلَوْ كَرِهَ ٱلْمُجْرِمُونَ","en":"That He should establish the truth and abolish falsehood, even if the criminals disliked it.","tr":"Liyuhiqqa alhaqqa wayubtilaalbatila walaw kariha almujrimoon","juz":9,"page":177},{"s":8,"a":9,"key":"8:9","ar":"إِذْ تَسْتَغِيثُونَ رَبَّكُمْ فَٱسْتَجَابَ لَكُمْ أَنِّى مُمِدُّكُم بِأَلْفٍ مِّنَ ٱلْمَلَـٰٓئِكَةِ مُرْدِفِينَ","en":"[Remember] when you were asking help of your Lord, and He answered you, \"Indeed, I will reinforce you with a thousand from the angels, following one another.\"","tr":"Ith tastagheethoona rabbakum fastajabalakum annee mumiddukum bi-alfin mina almala-ikatimurdifeen","juz":9,"page":178},{"s":8,"a":10,"key":"8:10","ar":"وَمَا جَعَلَهُ ٱللَّهُ إِلَّا بُشْرَىٰ وَلِتَطْمَئِنَّ بِهِۦ قُلُوبُكُمْ ۚ وَمَا ٱلنَّصْرُ إِلَّا مِنْ عِندِ ٱللَّهِ ۚ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ","en":"And Allāh made it not but good tidings and so that your hearts would be assured thereby. And victory is not but from Allāh. Indeed, Allāh is Exalted in Might and Wise.","tr":"Wama jaAAalahu Allahu illabushra walitatma-inna bihi quloobukum wama annasruilla min AAindi Allahi inna Allaha AAazeezunhakeem","juz":9,"page":178},{"s":8,"a":11,"key":"8:11","ar":"إِذْ يُغَشِّيكُمُ ٱلنُّعَاسَ أَمَنَةً مِّنْهُ وَيُنَزِّلُ عَلَيْكُم مِّنَ ٱلسَّمَآءِ مَآءً لِّيُطَهِّرَكُم بِهِۦ وَيُذْهِبَ عَنكُمْ رِجْزَ ٱلشَّيْطَـٰنِ وَلِيَرْبِطَ عَلَىٰ قُلُوبِكُمْ وَيُثَبِّتَ بِهِ ٱلْأَقْدَامَ","en":"[Remember] when He overwhelmed you with drowsiness [giving] security from Him and sent down upon you from the sky, rain by which to purify you and remove from you the evil [suggestions] of Satan and to make steadfast your hearts and plant firmly thereby your feet.","tr":"Ith yughashsheekumu annuAAasaamanatan minhu wayunazzilu AAalaykum mina assama-imaan liyutahhirakum bihi wayuthhiba AAankumrijza ashshaytani waliyarbita AAalaquloobikum wayuthabbita bihi al-aqdam","juz":9,"page":178},{"s":8,"a":12,"key":"8:12","ar":"إِذْ يُوحِى رَبُّكَ إِلَى ٱلْمَلَـٰٓئِكَةِ أَنِّى مَعَكُمْ فَثَبِّتُوا۟ ٱلَّذِينَ ءَامَنُوا۟ ۚ سَأُلْقِى فِى قُلُوبِ ٱلَّذِينَ كَفَرُوا۟ ٱلرُّعْبَ فَٱضْرِبُوا۟ فَوْقَ ٱلْأَعْنَاقِ وَٱضْرِبُوا۟ مِنْهُمْ كُلَّ بَنَانٍ","en":"[Remember] when your Lord inspired to the angels, \"I am with you, so strengthen those who have believed. I will cast terror into the hearts of those who disbelieved, so strike [them] upon the necks and strike from them every fingertip.\"1","tr":"Ith yoohee rabbuka ilaalmala-ikati annee maAAakum fathabbitoo allatheena amanoosaolqee fee quloobi allatheena kafaroo arruAAba fadriboofawqa al-aAAnaqi wadriboo minhum kulla banan","juz":9,"page":178},{"s":8,"a":13,"key":"8:13","ar":"ذَٰلِكَ بِأَنَّهُمْ شَآقُّوا۟ ٱللَّهَ وَرَسُولَهُۥ ۚ وَمَن يُشَاقِقِ ٱللَّهَ وَرَسُولَهُۥ فَإِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ","en":"That is because they opposed Allāh and His Messenger. And whoever opposes Allāh and His Messenger - indeed, Allāh is severe in penalty.","tr":"Thalika bi-annahum shaqqoo Allahawarasoolahu waman yushaqiqi Allaha warasoolahufa-inna Allaha shadeedu alAAiqab","juz":9,"page":178},{"s":8,"a":14,"key":"8:14","ar":"ذَٰلِكُمْ فَذُوقُوهُ وَأَنَّ لِلْكَـٰفِرِينَ عَذَابَ ٱلنَّارِ","en":"\"That [is yours], so taste it.\" And indeed for the disbelievers is the punishment of the Fire.","tr":"Thalikum fathooqoohu waannalilkafireena AAathaba annar","juz":9,"page":178},{"s":8,"a":15,"key":"8:15","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا لَقِيتُمُ ٱلَّذِينَ كَفَرُوا۟ زَحْفًا فَلَا تُوَلُّوهُمُ ٱلْأَدْبَارَ","en":"O you who have believed, when you meet those who disbelieve advancing [in battle], do not turn to them your backs [in flight].","tr":"Ya ayyuha allatheena amanooitha laqeetumu allatheena kafaroo zahfan falatuwalloohumu al-adbar","juz":9,"page":178},{"s":8,"a":16,"key":"8:16","ar":"وَمَن يُوَلِّهِمْ يَوْمَئِذٍ دُبُرَهُۥٓ إِلَّا مُتَحَرِّفًا لِّقِتَالٍ أَوْ مُتَحَيِّزًا إِلَىٰ فِئَةٍ فَقَدْ بَآءَ بِغَضَبٍ مِّنَ ٱللَّهِ وَمَأْوَىٰهُ جَهَنَّمُ ۖ وَبِئْسَ ٱلْمَصِيرُ","en":"And whoever turns his back to them on such a day, unless swerving [as a strategy] for war or joining [another] company, has certainly returned with anger [upon him] from Allāh, and his refuge is Hell - and wretched is the destination.","tr":"Waman yuwallihim yawma-ithin duburahuilla mutaharrifan liqitalin aw mutahayyizanila fi-atin faqad baa bighadabin mina Allahiwama/wahu jahannamu wabi/sa almaseer","juz":9,"page":178},{"s":8,"a":17,"key":"8:17","ar":"فَلَمْ تَقْتُلُوهُمْ وَلَـٰكِنَّ ٱللَّهَ قَتَلَهُمْ ۚ وَمَا رَمَيْتَ إِذْ رَمَيْتَ وَلَـٰكِنَّ ٱللَّهَ رَمَىٰ ۚ وَلِيُبْلِىَ ٱلْمُؤْمِنِينَ مِنْهُ بَلَآءً حَسَنًا ۚ إِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌ","en":"And you did not kill them, but it was Allāh who killed them.1 And you threw not, [O Muḥammad], when you threw, but it was Allāh who threw2 that He might test the believers with a good test.3 Indeed, Allāh is Hearing and Knowing.","tr":"Falam taqtuloohum walakinna Allahaqatalahum wama ramayta ith ramayta walakinnaAllaha rama waliyubliya almu/mineena minhu balaanhasanan inna Allaha sameeAAun AAaleem","juz":9,"page":179},{"s":8,"a":18,"key":"8:18","ar":"ذَٰلِكُمْ وَأَنَّ ٱللَّهَ مُوهِنُ كَيْدِ ٱلْكَـٰفِرِينَ","en":"That [is so], and [also] that Allāh will weaken the plot of the disbelievers.","tr":"Thalikum waanna Allaha moohinukaydi alkafireen","juz":9,"page":179},{"s":8,"a":19,"key":"8:19","ar":"إِن تَسْتَفْتِحُوا۟ فَقَدْ جَآءَكُمُ ٱلْفَتْحُ ۖ وَإِن تَنتَهُوا۟ فَهُوَ خَيْرٌ لَّكُمْ ۖ وَإِن تَعُودُوا۟ نَعُدْ وَلَن تُغْنِىَ عَنكُمْ فِئَتُكُمْ شَيْـًٔا وَلَوْ كَثُرَتْ وَأَنَّ ٱللَّهَ مَعَ ٱلْمُؤْمِنِينَ","en":"If you [disbelievers] seek the decision [i.e., victory] - the decision [i.e., defeat] has come to you. And if you desist [from hostilities], it is best for you; but if you return [to war], We will return, and never will you be availed by your [large] company at all, even if it should increase; and [that is] because Allāh is with the believers.","tr":"In tastaftihoo faqad jaakumualfathu wa-in tantahoo fahuwa khayrun lakum wa-intaAAoodoo naAAud walan tughniya AAankum fi-atukum shay-an walawkathurat waanna Allaha maAAa almu/mineen","juz":9,"page":179},{"s":8,"a":20,"key":"8:20","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَطِيعُوا۟ ٱللَّهَ وَرَسُولَهُۥ وَلَا تَوَلَّوْا۟ عَنْهُ وَأَنتُمْ تَسْمَعُونَ","en":"O you who have believed, obey Allāh and His Messenger and do not turn from him while you hear [his order].","tr":"Ya ayyuha allatheena amanooateeAAoo Allaha warasoolahu wala tawallawAAanhu waantum tasmaAAoon","juz":9,"page":179},{"s":8,"a":21,"key":"8:21","ar":"وَلَا تَكُونُوا۟ كَٱلَّذِينَ قَالُوا۟ سَمِعْنَا وَهُمْ لَا يَسْمَعُونَ","en":"And do not be like those who say, \"We have heard,\" while they do not hear.","tr":"Wala takoonoo kallatheenaqaloo samiAAna wahum la yasmaAAoon","juz":9,"page":179},{"s":8,"a":22,"key":"8:22","ar":"۞ إِنَّ شَرَّ ٱلدَّوَآبِّ عِندَ ٱللَّهِ ٱلصُّمُّ ٱلْبُكْمُ ٱلَّذِينَ لَا يَعْقِلُونَ","en":"Indeed, the worst of living creatures in the sight of Allāh are the deaf and dumb who do not use reason [i.e., the disbelievers].","tr":"Inna sharra addawabbi AAindaAllahi assummu albukmu allatheena layaAAqiloon","juz":9,"page":179},{"s":8,"a":23,"key":"8:23","ar":"وَلَوْ عَلِمَ ٱللَّهُ فِيهِمْ خَيْرًا لَّأَسْمَعَهُمْ ۖ وَلَوْ أَسْمَعَهُمْ لَتَوَلَّوا۟ وَّهُم مُّعْرِضُونَ","en":"Had Allāh known any good in them, He would have made them hear. And if He had made them hear, they would [still] have turned away, while they were refusing.","tr":"Walaw AAalima Allahu feehim khayranlaasmaAAahum walaw asmaAAahum latawallaw wahum muAAridoon","juz":9,"page":179},{"s":8,"a":24,"key":"8:24","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱسْتَجِيبُوا۟ لِلَّهِ وَلِلرَّسُولِ إِذَا دَعَاكُمْ لِمَا يُحْيِيكُمْ ۖ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ يَحُولُ بَيْنَ ٱلْمَرْءِ وَقَلْبِهِۦ وَأَنَّهُۥٓ إِلَيْهِ تُحْشَرُونَ","en":"O you who have believed, respond to Allāh and to the Messenger when he calls you to that which gives you life. And know that Allāh intervenes between a man and his heart and that to Him you will be gathered.","tr":"Yaayyuha allatheena amanooistajeeboo lillahi walirrasooli itha daAAakumlima yuhyeekum waAAlamoo anna Allahayahoolu bayna almar-i waqalbihi waannahu ilayhi tuhsharoon","juz":9,"page":179},{"s":8,"a":25,"key":"8:25","ar":"وَٱتَّقُوا۟ فِتْنَةً لَّا تُصِيبَنَّ ٱلَّذِينَ ظَلَمُوا۟ مِنكُمْ خَآصَّةً ۖ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ","en":"And fear a trial1 which will not strike those who have wronged among you exclusively, and know that Allāh is severe in penalty.","tr":"Wattaqoo fitnatan la tuseebannaallatheena thalamoo minkum khassatanwaAAlamoo anna Allaha shadeedu alAAiqab","juz":9,"page":179},{"s":8,"a":26,"key":"8:26","ar":"وَٱذْكُرُوٓا۟ إِذْ أَنتُمْ قَلِيلٌ مُّسْتَضْعَفُونَ فِى ٱلْأَرْضِ تَخَافُونَ أَن يَتَخَطَّفَكُمُ ٱلنَّاسُ فَـَٔاوَىٰكُمْ وَأَيَّدَكُم بِنَصْرِهِۦ وَرَزَقَكُم مِّنَ ٱلطَّيِّبَـٰتِ لَعَلَّكُمْ تَشْكُرُونَ","en":"And remember when you were few and oppressed in the land, fearing that people might abduct you, but He sheltered you, supported you with His victory, and provided you with good things - that you might be grateful.","tr":"Wathkuroo ith antumqaleelun mustadAAafoona fee al-ardi takhafoonaan yatakhattafakumu annasu faawakumwaayyadakum binasrihi warazaqakum mina attayyibatilaAAallakum tashkuroon","juz":9,"page":180},{"s":8,"a":27,"key":"8:27","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَخُونُوا۟ ٱللَّهَ وَٱلرَّسُولَ وَتَخُونُوٓا۟ أَمَـٰنَـٰتِكُمْ وَأَنتُمْ تَعْلَمُونَ","en":"O you who have believed, do not betray Allāh and the Messenger or betray your trusts while you know [the consequence].","tr":"Ya ayyuha allatheena amanoola takhoonoo Allaha warrasoola watakhoonooamanatikum waantum taAAlamoon","juz":9,"page":180},{"s":8,"a":28,"key":"8:28","ar":"وَٱعْلَمُوٓا۟ أَنَّمَآ أَمْوَٰلُكُمْ وَأَوْلَـٰدُكُمْ فِتْنَةٌ وَأَنَّ ٱللَّهَ عِندَهُۥٓ أَجْرٌ عَظِيمٌ","en":"And know that your properties and your children are but a trial and that Allāh has with Him a great reward.","tr":"WaAAlamoo annama amwalukumwaawladukum fitnatun waanna Allaha AAindahu ajrunAAatheem","juz":9,"page":180},{"s":8,"a":29,"key":"8:29","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تَتَّقُوا۟ ٱللَّهَ يَجْعَل لَّكُمْ فُرْقَانًا وَيُكَفِّرْ عَنكُمْ سَيِّـَٔاتِكُمْ وَيَغْفِرْ لَكُمْ ۗ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ","en":"O you who have believed, if you fear Allāh, He will grant you a criterion1 and will remove from you your misdeeds and forgive you. And Allāh is the possessor of great bounty.","tr":"Ya ayyuha allatheena amanooin tattaqoo Allaha yajAAal lakum furqananwayukaffir AAankum sayyi-atikum wayaghfir lakum wallahuthoo alfadli alAAatheem","juz":9,"page":180},{"s":8,"a":30,"key":"8:30","ar":"وَإِذْ يَمْكُرُ بِكَ ٱلَّذِينَ كَفَرُوا۟ لِيُثْبِتُوكَ أَوْ يَقْتُلُوكَ أَوْ يُخْرِجُوكَ ۚ وَيَمْكُرُونَ وَيَمْكُرُ ٱللَّهُ ۖ وَٱللَّهُ خَيْرُ ٱلْمَـٰكِرِينَ","en":"And [remember, O Muḥammad], when those who disbelieved plotted against you to restrain you or kill you or evict you [from Makkah]. But they plan, and Allāh plans. And Allāh is the best of planners.","tr":"Wa-ith yamkuru bika allatheenakafaroo liyuthbitooka aw yaqtulooka aw yukhrijooka wayamkuroonawayamkuru Allahu wallahu khayru almakireen","juz":9,"page":180},{"s":8,"a":31,"key":"8:31","ar":"وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَـٰتُنَا قَالُوا۟ قَدْ سَمِعْنَا لَوْ نَشَآءُ لَقُلْنَا مِثْلَ هَـٰذَآ ۙ إِنْ هَـٰذَآ إِلَّآ أَسَـٰطِيرُ ٱلْأَوَّلِينَ","en":"And when Our verses are recited to them, they say, \"We have heard. If we willed, we could say [something] like this. This is not but legends of the former peoples.\"","tr":"Wa-itha tutla AAalayhim ayatunaqaloo qad samiAAna law nashao laqulnamithla hatha in hatha illa asateerual-awwaleen","juz":9,"page":180},{"s":8,"a":32,"key":"8:32","ar":"وَإِذْ قَالُوا۟ ٱللَّهُمَّ إِن كَانَ هَـٰذَا هُوَ ٱلْحَقَّ مِنْ عِندِكَ فَأَمْطِرْ عَلَيْنَا حِجَارَةً مِّنَ ٱلسَّمَآءِ أَوِ ٱئْتِنَا بِعَذَابٍ أَلِيمٍ","en":"And [remember] when they said, \"O Allāh, if this should be the truth from You, then rain down upon us stones from the sky or bring us a painful punishment.\"","tr":"Wa-ith qaloo allahummain kana hatha huwa alhaqqa min AAindika faamtirAAalayna hijaratan mina assama-iawi i/tina biAAathabin aleem","juz":9,"page":180},{"s":8,"a":33,"key":"8:33","ar":"وَمَا كَانَ ٱللَّهُ لِيُعَذِّبَهُمْ وَأَنتَ فِيهِمْ ۚ وَمَا كَانَ ٱللَّهُ مُعَذِّبَهُمْ وَهُمْ يَسْتَغْفِرُونَ","en":"But Allāh would not punish them while you, [O Muḥammad], are among them, and Allāh would not punish them while they seek forgiveness.","tr":"Wama kana AllahuliyuAAaththibahum waanta feehim wama kanaAllahu muAAaththibahum wahum yastaghfiroon","juz":9,"page":180},{"s":8,"a":34,"key":"8:34","ar":"وَمَا لَهُمْ أَلَّا يُعَذِّبَهُمُ ٱللَّهُ وَهُمْ يَصُدُّونَ عَنِ ٱلْمَسْجِدِ ٱلْحَرَامِ وَمَا كَانُوٓا۟ أَوْلِيَآءَهُۥٓ ۚ إِنْ أَوْلِيَآؤُهُۥٓ إِلَّا ٱلْمُتَّقُونَ وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ","en":"But why should Allāh not punish them while they obstruct [people] from al-Masjid al-Ḥarām and they were not [fit to be] its guardians? Its [true] guardians are not but the righteous, but most of them do not know.","tr":"Wama lahum alla yuAAaththibahumuAllahu wahum yasuddoona AAani almasjidi alharamiwama kanoo awliyaahu in awliyaohu illaalmuttaqoona walakinna aktharahum la yaAAlamoon","juz":9,"page":181},{"s":8,"a":35,"key":"8:35","ar":"وَمَا كَانَ صَلَاتُهُمْ عِندَ ٱلْبَيْتِ إِلَّا مُكَآءً وَتَصْدِيَةً ۚ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْفُرُونَ","en":"And their prayer at the House [i.e., the Kaʿbah] was not except whistling and handclapping. So taste the punishment for what you disbelieved [i.e., practiced of deviations].","tr":"Wama kana salatuhumAAinda albayti illa mukaan watasdiyatan fathooqooalAAathaba bima kuntum takfuroon","juz":9,"page":181},{"s":8,"a":36,"key":"8:36","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ يُنفِقُونَ أَمْوَٰلَهُمْ لِيَصُدُّوا۟ عَن سَبِيلِ ٱللَّهِ ۚ فَسَيُنفِقُونَهَا ثُمَّ تَكُونُ عَلَيْهِمْ حَسْرَةً ثُمَّ يُغْلَبُونَ ۗ وَٱلَّذِينَ كَفَرُوٓا۟ إِلَىٰ جَهَنَّمَ يُحْشَرُونَ","en":"Indeed, those who disbelieve spend their wealth to avert [people] from the way of Allāh. So they will spend it; then it will be for them a [source of] regret; then they will be overcome. And those who have disbelieved - unto Hell they will be gathered.","tr":"Inna allatheena kafaroo yunfiqoonaamwalahum liyasuddoo AAan sabeeli Allahifasayunfiqoonaha thumma takoonu AAalayhim hasratanthumma yughlaboona wallatheena kafaroo ilajahannama yuhsharoon","juz":9,"page":181},{"s":8,"a":37,"key":"8:37","ar":"لِيَمِيزَ ٱللَّهُ ٱلْخَبِيثَ مِنَ ٱلطَّيِّبِ وَيَجْعَلَ ٱلْخَبِيثَ بَعْضَهُۥ عَلَىٰ بَعْضٍ فَيَرْكُمَهُۥ جَمِيعًا فَيَجْعَلَهُۥ فِى جَهَنَّمَ ۚ أُو۟لَـٰٓئِكَ هُمُ ٱلْخَـٰسِرُونَ","en":"[It is] so that Allāh may distinguish the wicked from the good and place the wicked some of them upon others and heap them all together and put them into Hell. It is those who are the losers.","tr":"Liyameeza Allahu alkhabeetha mina attayyibiwayajAAala alkhabeetha baAAdahu AAala baAAdinfayarkumahu jameeAAan fayajAAalahu fee jahannama ola-ikahumu alkhasiroon","juz":9,"page":181},{"s":8,"a":38,"key":"8:38","ar":"قُل لِّلَّذِينَ كَفَرُوٓا۟ إِن يَنتَهُوا۟ يُغْفَرْ لَهُم مَّا قَدْ سَلَفَ وَإِن يَعُودُوا۟ فَقَدْ مَضَتْ سُنَّتُ ٱلْأَوَّلِينَ","en":"Say to those who have disbelieved [that] if they cease, what has previously occurred will be forgiven for them. But if they return [to hostility] - then the precedent of the former [rebellious] peoples has already taken place.1","tr":"Qul lillatheena kafaroo in yantahooyughfar lahum ma qad salafa wa-in yaAAoodoo faqad madatsunnatu al-awwaleen","juz":9,"page":181},{"s":8,"a":39,"key":"8:39","ar":"وَقَـٰتِلُوهُمْ حَتَّىٰ لَا تَكُونَ فِتْنَةٌ وَيَكُونَ ٱلدِّينُ كُلُّهُۥ لِلَّهِ ۚ فَإِنِ ٱنتَهَوْا۟ فَإِنَّ ٱللَّهَ بِمَا يَعْمَلُونَ بَصِيرٌ","en":"And fight against them until there is no fitnah1 and [until] the religion [i.e., worship], all of it, is for Allāh.2 And if they cease - then indeed, Allāh is Seeing of what they do.","tr":"Waqatiloohum hatta latakoona fitnatun wayakoona addeenu kulluhu lillahifa-ini intahaw fa-inna Allaha bima yaAAmaloona baseer","juz":9,"page":181},{"s":8,"a":40,"key":"8:40","ar":"وَإِن تَوَلَّوْا۟ فَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ مَوْلَىٰكُمْ ۚ نِعْمَ ٱلْمَوْلَىٰ وَنِعْمَ ٱلنَّصِيرُ","en":"But if they turn away - then know that Allāh is your protector. Excellent is the protector, and excellent is the helper.","tr":"Wa-in tawallaw faAAlamoo anna Allahamawlakum niAAma almawla waniAAma annaseer","juz":9,"page":181},{"s":8,"a":41,"key":"8:41","ar":"۞ وَٱعْلَمُوٓا۟ أَنَّمَا غَنِمْتُم مِّن شَىْءٍ فَأَنَّ لِلَّهِ خُمُسَهُۥ وَلِلرَّسُولِ وَلِذِى ٱلْقُرْبَىٰ وَٱلْيَتَـٰمَىٰ وَٱلْمَسَـٰكِينِ وَٱبْنِ ٱلسَّبِيلِ إِن كُنتُمْ ءَامَنتُم بِٱللَّهِ وَمَآ أَنزَلْنَا عَلَىٰ عَبْدِنَا يَوْمَ ٱلْفُرْقَانِ يَوْمَ ٱلْتَقَى ٱلْجَمْعَانِ ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"And know that anything you obtain of war booty - then indeed, for Allāh is one fifth of it and for the Messenger1 and for [his] near relatives2 and the orphans, the needy, and the [stranded] traveler,3 if you have believed in Allāh and in that which We sent down to Our Servant4 on the day of criterion [i.e., decisive encounter] - the day when the two armies met [at Badr]. And Allāh, over all things, is competent.","tr":"WaAAlamoo annama ghanimtummin shay-in faanna lillahi khumusahu walirrasooliwalithee alqurba walyatama walmasakeeniwabni assabeeli in kuntum amantum billahiwama anzalna AAala AAabdina yawmaalfurqani yawma iltaqa aljamAAani wallahuAAala kulli shay-in qadeer","juz":10,"page":182},{"s":8,"a":42,"key":"8:42","ar":"إِذْ أَنتُم بِٱلْعُدْوَةِ ٱلدُّنْيَا وَهُم بِٱلْعُدْوَةِ ٱلْقُصْوَىٰ وَٱلرَّكْبُ أَسْفَلَ مِنكُمْ ۚ وَلَوْ تَوَاعَدتُّمْ لَٱخْتَلَفْتُمْ فِى ٱلْمِيعَـٰدِ ۙ وَلَـٰكِن لِّيَقْضِىَ ٱللَّهُ أَمْرًا كَانَ مَفْعُولًا لِّيَهْلِكَ مَنْ هَلَكَ عَنۢ بَيِّنَةٍ وَيَحْيَىٰ مَنْ حَىَّ عَنۢ بَيِّنَةٍ ۗ وَإِنَّ ٱللَّهَ لَسَمِيعٌ عَلِيمٌ","en":"[Remember] when you were on the near side of the valley, and they were on the farther side, and the caravan was lower [in position] than you. If you had made an appointment [to meet], you would have missed the appointment. But [it was] so that Allāh might accomplish a matter already destined - that those who perished [through disbelief] would perish upon evidence and those who lived [in faith] would live upon evidence; and indeed, Allāh is Hearing and Knowing.","tr":"Ith antum bilAAudwati addunyawahum bilAAudwati alquswa warrakbuasfala minkum walaw tawaAAadtum lakhtalaftum feealmeeAAadi walakin liyaqdiya Allahuamran kana mafAAoolan liyahlika man halaka AAan bayyinatinwayahya man hayya AAan bayyinatin wa-innaAllaha lasameeAAun AAaleem","juz":10,"page":182},{"s":8,"a":43,"key":"8:43","ar":"إِذْ يُرِيكَهُمُ ٱللَّهُ فِى مَنَامِكَ قَلِيلًا ۖ وَلَوْ أَرَىٰكَهُمْ كَثِيرًا لَّفَشِلْتُمْ وَلَتَنَـٰزَعْتُمْ فِى ٱلْأَمْرِ وَلَـٰكِنَّ ٱللَّهَ سَلَّمَ ۗ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"[Remember, O Muḥammad], when Allāh showed them to you in your dream as few; and if He had shown them to you as many, you [believers] would have lost courage and would have disputed in the matter [of whether to fight], but Allāh saved [you from that]. Indeed, He is Knowing of that within the breasts.","tr":"Ith yureekahumu Allahu fee manamikaqaleelan walaw arakahum katheeran lafashiltum walatanazaAAtumfee al-amri walakinna Allaha sallama innahuAAaleemun bithati assudoor","juz":10,"page":182},{"s":8,"a":44,"key":"8:44","ar":"وَإِذْ يُرِيكُمُوهُمْ إِذِ ٱلْتَقَيْتُمْ فِىٓ أَعْيُنِكُمْ قَلِيلًا وَيُقَلِّلُكُمْ فِىٓ أَعْيُنِهِمْ لِيَقْضِىَ ٱللَّهُ أَمْرًا كَانَ مَفْعُولًا ۗ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ","en":"And [remember] when He showed them to you, when you met, as few in your eyes, and He made you [appear] as few in their eyes so that Allāh might accomplish a matter already destined. And to Allāh are [all] matters returned.","tr":"Wa-ith yureekumoohum ithiiltaqaytum fee aAAyunikum qaleelan wayuqallilukum fee aAAyunihimliyaqdiya Allahu amran kana mafAAoolan wa-ilaAllahi turjaAAu al-omoor","juz":10,"page":182},{"s":8,"a":45,"key":"8:45","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا لَقِيتُمْ فِئَةً فَٱثْبُتُوا۟ وَٱذْكُرُوا۟ ٱللَّهَ كَثِيرًا لَّعَلَّكُمْ تُفْلِحُونَ","en":"O you who have believed, when you encounter a company [from the enemy forces], stand firm and remember Allāh much that you may be successful.","tr":"Ya ayyuha allatheena amanooitha laqeetum fi-atan fathbutoo wathkurooAllaha katheeran laAAallakum tuflihoon","juz":10,"page":182},{"s":8,"a":46,"key":"8:46","ar":"وَأَطِيعُوا۟ ٱللَّهَ وَرَسُولَهُۥ وَلَا تَنَـٰزَعُوا۟ فَتَفْشَلُوا۟ وَتَذْهَبَ رِيحُكُمْ ۖ وَٱصْبِرُوٓا۟ ۚ إِنَّ ٱللَّهَ مَعَ ٱلصَّـٰبِرِينَ","en":"And obey Allāh and His Messenger, and do not dispute and [thus] lose courage and [then] your strength would depart; and be patient. Indeed, Allāh is with the patient.","tr":"WaateeAAoo Allaha warasoolahuwala tanazaAAoo fatafshaloo watathhaba reehukumwasbiroo inna Allaha maAAa assabireen","juz":10,"page":183},{"s":8,"a":47,"key":"8:47","ar":"وَلَا تَكُونُوا۟ كَٱلَّذِينَ خَرَجُوا۟ مِن دِيَـٰرِهِم بَطَرًا وَرِئَآءَ ٱلنَّاسِ وَيَصُدُّونَ عَن سَبِيلِ ٱللَّهِ ۚ وَٱللَّهُ بِمَا يَعْمَلُونَ مُحِيطٌ","en":"And do not be like those who came forth from their homes insolently and to be seen by people and avert [them] from the way of Allāh. And Allāh is encompassing1 of what they do.","tr":"Wala takoonoo kallatheenakharajoo min diyarihim bataran wari-aa annasiwayasuddoona AAan sabeeli Allahi wallahubima yaAAmaloona muheet","juz":10,"page":183},{"s":8,"a":48,"key":"8:48","ar":"وَإِذْ زَيَّنَ لَهُمُ ٱلشَّيْطَـٰنُ أَعْمَـٰلَهُمْ وَقَالَ لَا غَالِبَ لَكُمُ ٱلْيَوْمَ مِنَ ٱلنَّاسِ وَإِنِّى جَارٌ لَّكُمْ ۖ فَلَمَّا تَرَآءَتِ ٱلْفِئَتَانِ نَكَصَ عَلَىٰ عَقِبَيْهِ وَقَالَ إِنِّى بَرِىٓءٌ مِّنكُمْ إِنِّىٓ أَرَىٰ مَا لَا تَرَوْنَ إِنِّىٓ أَخَافُ ٱللَّهَ ۚ وَٱللَّهُ شَدِيدُ ٱلْعِقَابِ","en":"And [remember] when Satan made their deeds pleasing to them and said, \"No one can overcome you today from among the people, and indeed, I am your protector.\" But when the two armies sighted each other, he turned on his heels and said, \"Indeed, I am disassociated from you. Indeed, I see what you do not see; indeed, I fear Allāh. And Allāh is severe in penalty.\"","tr":"Wa-ith zayyana lahumu ashshaytanuaAAmalahum waqala la ghaliba lakumualyawma mina annasi wa-innee jarun lakumfalamma taraati alfi-atani nakasaAAala AAaqibayhi waqala innee baree-on minkum inneeara ma la tarawna innee akhafu Allahawallahu shadeedu alAAiqab","juz":10,"page":183},{"s":8,"a":49,"key":"8:49","ar":"إِذْ يَقُولُ ٱلْمُنَـٰفِقُونَ وَٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌ غَرَّ هَـٰٓؤُلَآءِ دِينُهُمْ ۗ وَمَن يَتَوَكَّلْ عَلَى ٱللَّهِ فَإِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ","en":"[Remember] when the hypocrites and those in whose hearts was disease [i.e., arrogance and disbelief] said, \"Their religion has deluded those [Muslims].\" But whoever relies upon Allāh - then indeed, Allāh is Exalted in Might and Wise.","tr":"Ith yaqoolu almunafiqoona wallatheenafee quloobihim maradun gharra haola-ideenuhum waman yatawakkal AAala Allahi fa-inna AllahaAAazeezun hakeem","juz":10,"page":183},{"s":8,"a":50,"key":"8:50","ar":"وَلَوْ تَرَىٰٓ إِذْ يَتَوَفَّى ٱلَّذِينَ كَفَرُوا۟ ۙ ٱلْمَلَـٰٓئِكَةُ يَضْرِبُونَ وُجُوهَهُمْ وَأَدْبَـٰرَهُمْ وَذُوقُوا۟ عَذَابَ ٱلْحَرِيقِ","en":"And if you could but see when the angels take the souls of those who disbelieved...1 They are striking their faces and their backs and [saying], \"Taste the punishment of the Burning Fire.","tr":"Walaw tara ith yatawaffaallatheena kafaroo almala-ikatu yadriboonawujoohahum waadbarahum wathooqoo AAathaba alhareeq","juz":10,"page":183},{"s":8,"a":51,"key":"8:51","ar":"ذَٰلِكَ بِمَا قَدَّمَتْ أَيْدِيكُمْ وَأَنَّ ٱللَّهَ لَيْسَ بِظَلَّـٰمٍ لِّلْعَبِيدِ","en":"That is for what your hands have put forth [of evil] and because Allāh is not ever unjust to [His] servants.\"","tr":"Thalika bima qaddamat aydeekumwaanna Allaha laysa bithallaminlilAAabeed","juz":10,"page":183},{"s":8,"a":52,"key":"8:52","ar":"كَدَأْبِ ءَالِ فِرْعَوْنَ ۙ وَٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَفَرُوا۟ بِـَٔايَـٰتِ ٱللَّهِ فَأَخَذَهُمُ ٱللَّهُ بِذُنُوبِهِمْ ۗ إِنَّ ٱللَّهَ قَوِىٌّ شَدِيدُ ٱلْعِقَابِ","en":"[Theirs is] like the custom of the people of Pharaoh and of those before them. They disbelieved in the signs of Allāh, so Allāh seized them for their sins. Indeed, Allāh is Powerful and severe in penalty.","tr":"Kada/bi ali firAAawna wallatheenamin qablihim kafaroo bi-ayati Allahi faakhathahumuAllahu bithunoobihim inna Allaha qawiyyunshadeedu alAAiqab","juz":10,"page":183},{"s":8,"a":53,"key":"8:53","ar":"ذَٰلِكَ بِأَنَّ ٱللَّهَ لَمْ يَكُ مُغَيِّرًا نِّعْمَةً أَنْعَمَهَا عَلَىٰ قَوْمٍ حَتَّىٰ يُغَيِّرُوا۟ مَا بِأَنفُسِهِمْ ۙ وَأَنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌ","en":"That is because Allāh would not change a favor which He had bestowed upon a people until they change what is within themselves. And indeed, Allāh is Hearing and Knowing.","tr":"Thalika bi-anna Allaha lamyaku mughayyiran niAAmatan anAAamaha AAala qawmin hattayughayyiroo ma bi-anfusihim waanna Allaha sameeAAunAAaleem","juz":10,"page":184},{"s":8,"a":54,"key":"8:54","ar":"كَدَأْبِ ءَالِ فِرْعَوْنَ ۙ وَٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَذَّبُوا۟ بِـَٔايَـٰتِ رَبِّهِمْ فَأَهْلَكْنَـٰهُم بِذُنُوبِهِمْ وَأَغْرَقْنَآ ءَالَ فِرْعَوْنَ ۚ وَكُلٌّ كَانُوا۟ ظَـٰلِمِينَ","en":"[Theirs is] like the custom of the people of Pharaoh and of those before them. They denied the signs of their Lord, so We destroyed them for their sins, and We drowned the people of Pharaoh. And all [of them] were wrongdoers.","tr":"Kada/bi ali firAAawna wallatheenamin qablihim kaththaboo bi-ayati rabbihimfaahlaknahum bithunoobihim waaghraqna alafirAAawna wakullun kanoo thalimeen","juz":10,"page":184},{"s":8,"a":55,"key":"8:55","ar":"إِنَّ شَرَّ ٱلدَّوَآبِّ عِندَ ٱللَّهِ ٱلَّذِينَ كَفَرُوا۟ فَهُمْ لَا يُؤْمِنُونَ","en":"Indeed, the worst of living creatures in the sight of Allāh are those who have disbelieved, and they will not [ever] believe-","tr":"Inna sharra addawabbi AAindaAllahi allatheena kafaroo fahum la yu/minoon","juz":10,"page":184},{"s":8,"a":56,"key":"8:56","ar":"ٱلَّذِينَ عَـٰهَدتَّ مِنْهُمْ ثُمَّ يَنقُضُونَ عَهْدَهُمْ فِى كُلِّ مَرَّةٍ وَهُمْ لَا يَتَّقُونَ","en":"The ones with whom you made a treaty but then they break their pledge every time, and they do not fear Allāh.","tr":"Allatheena AAahadta minhumthumma yanqudoona AAahdahum fee kulli marratin wahum layattaqoon","juz":10,"page":184},{"s":8,"a":57,"key":"8:57","ar":"فَإِمَّا تَثْقَفَنَّهُمْ فِى ٱلْحَرْبِ فَشَرِّدْ بِهِم مَّنْ خَلْفَهُمْ لَعَلَّهُمْ يَذَّكَّرُونَ","en":"So if you, [O Muḥammad], gain dominance over them in war, disperse by [means of] them those behind them that perhaps they will be reminded.1","tr":"Fa-imma tathqafannahum fee alharbifasharrid bihim man khalfahum laAAallahum yaththakkaroon","juz":10,"page":184},{"s":8,"a":58,"key":"8:58","ar":"وَإِمَّا تَخَافَنَّ مِن قَوْمٍ خِيَانَةً فَٱنۢبِذْ إِلَيْهِمْ عَلَىٰ سَوَآءٍ ۚ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْخَآئِنِينَ","en":"If you [have reason to] fear from a people betrayal, throw [their treaty] back to them, [putting you] on equal terms.1 Indeed, Allāh does not like traitors.","tr":"Wa-imma takhafanna min qawminkhiyanatan fanbith ilayhim AAalasawa-in inna Allaha la yuhibbu alkha-ineen","juz":10,"page":184},{"s":8,"a":59,"key":"8:59","ar":"وَلَا يَحْسَبَنَّ ٱلَّذِينَ كَفَرُوا۟ سَبَقُوٓا۟ ۚ إِنَّهُمْ لَا يُعْجِزُونَ","en":"And let not those who disbelieve think they will escape. Indeed, they will not cause failure [to Allāh].","tr":"Wala yahsabanna allatheenakafaroo sabaqoo innahum la yuAAjizoon","juz":10,"page":184},{"s":8,"a":60,"key":"8:60","ar":"وَأَعِدُّوا۟ لَهُم مَّا ٱسْتَطَعْتُم مِّن قُوَّةٍ وَمِن رِّبَاطِ ٱلْخَيْلِ تُرْهِبُونَ بِهِۦ عَدُوَّ ٱللَّهِ وَعَدُوَّكُمْ وَءَاخَرِينَ مِن دُونِهِمْ لَا تَعْلَمُونَهُمُ ٱللَّهُ يَعْلَمُهُمْ ۚ وَمَا تُنفِقُوا۟ مِن شَىْءٍ فِى سَبِيلِ ٱللَّهِ يُوَفَّ إِلَيْكُمْ وَأَنتُمْ لَا تُظْلَمُونَ","en":"And prepare against them whatever you are able of power and of steeds of war1 by which you may terrify the enemy of Allāh and your enemy and others besides them whom you do not know [but] whom Allāh knows. And whatever you spend in the cause of Allāh will be fully repaid to you, and you will not be wronged.","tr":"WaaAAiddoo lahum ma istataAAtummin quwwatin wamin ribati alkhayli turhiboona bihiAAaduwwa Allahi waAAaduwwakum waakhareena mindoonihim la taAAlamoonahumu Allahu yaAAlamuhum wamatunfiqoo min shay-in fee sabeeli Allahi yuwaffa ilaykumwaantum la tuthlamoon","juz":10,"page":184},{"s":8,"a":61,"key":"8:61","ar":"۞ وَإِن جَنَحُوا۟ لِلسَّلْمِ فَٱجْنَحْ لَهَا وَتَوَكَّلْ عَلَى ٱللَّهِ ۚ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"And if they incline to peace, then incline to it [also] and rely upon Allāh. Indeed, it is He who is the Hearing, the Knowing.","tr":"Wa-in janahoo lissalmi fajnahlaha watawakkal AAala Allahi innahu huwa assameeAAualAAaleem","juz":10,"page":184},{"s":8,"a":62,"key":"8:62","ar":"وَإِن يُرِيدُوٓا۟ أَن يَخْدَعُوكَ فَإِنَّ حَسْبَكَ ٱللَّهُ ۚ هُوَ ٱلَّذِىٓ أَيَّدَكَ بِنَصْرِهِۦ وَبِٱلْمُؤْمِنِينَ","en":"But if they intend to deceive you - then sufficient for you is Allāh. It is He who supported you with His help and with the believers","tr":"Wa-in yureedoo an yakhdaAAooka fa-inna hasbakaAllahu huwa allathee ayyadaka binasrihi wabilmu/mineen","juz":10,"page":185},{"s":8,"a":63,"key":"8:63","ar":"وَأَلَّفَ بَيْنَ قُلُوبِهِمْ ۚ لَوْ أَنفَقْتَ مَا فِى ٱلْأَرْضِ جَمِيعًا مَّآ أَلَّفْتَ بَيْنَ قُلُوبِهِمْ وَلَـٰكِنَّ ٱللَّهَ أَلَّفَ بَيْنَهُمْ ۚ إِنَّهُۥ عَزِيزٌ حَكِيمٌ","en":"And brought together their hearts. If you had spent all that is in the earth, you could not have brought their hearts together; but Allāh brought them together. Indeed, He is Exalted in Might and Wise.","tr":"Waallafa bayna quloobihim law anfaqta mafee al-ardi jameeAAan ma allafta bayna quloobihimwalakinna Allaha allafa baynahum innahu AAazeezun hakeem","juz":10,"page":185},{"s":8,"a":64,"key":"8:64","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ حَسْبُكَ ٱللَّهُ وَمَنِ ٱتَّبَعَكَ مِنَ ٱلْمُؤْمِنِينَ","en":"O Prophet, sufficient for you is Allāh and for whoever follows you of the believers.","tr":"Ya ayyuha annabiyyu hasbukaAllahu wamani ittabaAAaka mina almu/mineen","juz":10,"page":185},{"s":8,"a":65,"key":"8:65","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ حَرِّضِ ٱلْمُؤْمِنِينَ عَلَى ٱلْقِتَالِ ۚ إِن يَكُن مِّنكُمْ عِشْرُونَ صَـٰبِرُونَ يَغْلِبُوا۟ مِا۟ئَتَيْنِ ۚ وَإِن يَكُن مِّنكُم مِّا۟ئَةٌ يَغْلِبُوٓا۟ أَلْفًا مِّنَ ٱلَّذِينَ كَفَرُوا۟ بِأَنَّهُمْ قَوْمٌ لَّا يَفْقَهُونَ","en":"O Prophet, urge the believers to battle. If there are among you twenty [who are] steadfast, they will overcome two hundred. And if there are among you one hundred [who are steadfast], they will overcome a thousand of those who have disbelieved because they are a people who do not understand.","tr":"Ya ayyuha annabiyyu harridialmu/mineena AAala alqitali in yakun minkumAAishroona sabiroona yaghliboo mi-atayni wa-in yakunminkum mi-atun yaghliboo alfan mina allatheena kafaroobi-annahum qawmun la yafqahoon","juz":10,"page":185},{"s":8,"a":66,"key":"8:66","ar":"ٱلْـَٔـٰنَ خَفَّفَ ٱللَّهُ عَنكُمْ وَعَلِمَ أَنَّ فِيكُمْ ضَعْفًا ۚ فَإِن يَكُن مِّنكُم مِّا۟ئَةٌ صَابِرَةٌ يَغْلِبُوا۟ مِا۟ئَتَيْنِ ۚ وَإِن يَكُن مِّنكُمْ أَلْفٌ يَغْلِبُوٓا۟ أَلْفَيْنِ بِإِذْنِ ٱللَّهِ ۗ وَٱللَّهُ مَعَ ٱلصَّـٰبِرِينَ","en":"Now, Allāh has lightened [the hardship] for you, and He knows that among you is weakness. So if there are from you one hundred [who are] steadfast, they will overcome two hundred. And if there are among you a thousand, they will overcome two thousand by permission of Allāh. And Allāh is with the steadfast.","tr":"Al-ana khaffafa Allahu AAankumwaAAalima anna feekum daAAfan fa-in yakun minkum mi-atun sabiratunyaghliboo mi-atayni wa-in yakun minkum alfun yaghliboo alfaynibi-ithni Allahi wallahu maAAa assabireen","juz":10,"page":185},{"s":8,"a":67,"key":"8:67","ar":"مَا كَانَ لِنَبِىٍّ أَن يَكُونَ لَهُۥٓ أَسْرَىٰ حَتَّىٰ يُثْخِنَ فِى ٱلْأَرْضِ ۚ تُرِيدُونَ عَرَضَ ٱلدُّنْيَا وَٱللَّهُ يُرِيدُ ٱلْـَٔاخِرَةَ ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ","en":"It is not for a prophet to have captives [of war] until he inflicts a massacre [upon Allāh's enemies] in the land. You [i.e., some Muslims] desire the commodities of this world,1 but Allāh desires [for you] the Hereafter. And Allāh is Exalted in Might and Wise.","tr":"Ma kana linabiyyin an yakoonalahu asra hatta yuthkhina fee al-arditureedoona AAarada addunya wallahuyureedu al-akhirata wallahu AAazeezun hakeem","juz":10,"page":185},{"s":8,"a":68,"key":"8:68","ar":"لَّوْلَا كِتَـٰبٌ مِّنَ ٱللَّهِ سَبَقَ لَمَسَّكُمْ فِيمَآ أَخَذْتُمْ عَذَابٌ عَظِيمٌ","en":"If not for a decree from Allāh that preceded,1 you would have been touched for what you took by a great punishment.","tr":"Lawla kitabun mina Allahisabaqa lamassakum feema akhathtum AAathabunAAatheem","juz":10,"page":185},{"s":8,"a":69,"key":"8:69","ar":"فَكُلُوا۟ مِمَّا غَنِمْتُمْ حَلَـٰلًا طَيِّبًا ۚ وَٱتَّقُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"So consume what you have taken of war booty [as being] lawful and good, and fear Allāh. Indeed, Allāh is Forgiving and Merciful.","tr":"Fakuloo mimma ghanimtum halalantayyiban wattaqoo Allaha inna Allahaghafoorun raheem","juz":10,"page":185},{"s":8,"a":70,"key":"8:70","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ قُل لِّمَن فِىٓ أَيْدِيكُم مِّنَ ٱلْأَسْرَىٰٓ إِن يَعْلَمِ ٱللَّهُ فِى قُلُوبِكُمْ خَيْرًا يُؤْتِكُمْ خَيْرًا مِّمَّآ أُخِذَ مِنكُمْ وَيَغْفِرْ لَكُمْ ۗ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"O Prophet, say to whoever is in your hands of the captives, \"If Allāh knows [any] good in your hearts, He will give you [something] better than what was taken from you, and He will forgive you; and Allāh is Forgiving and Merciful.\"","tr":"Ya ayyuha annabiyyuqul liman fee aydeekum mina al-asra in yaAAlami Allahufee quloobikum khayran yu/tikum khayran mimma okhithaminkum wayaghfir lakum wallahu ghafoorun raheem","juz":10,"page":186},{"s":8,"a":71,"key":"8:71","ar":"وَإِن يُرِيدُوا۟ خِيَانَتَكَ فَقَدْ خَانُوا۟ ٱللَّهَ مِن قَبْلُ فَأَمْكَنَ مِنْهُمْ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"But if they intend to betray you - then they have already betrayed Allāh before, and He empowered [you] over them. And Allāh is Knowing and Wise.","tr":"Wa-in yureedoo khiyanataka faqad khanooAllaha min qablu faamkana minhum wallahuAAaleemun hakeem","juz":10,"page":186},{"s":8,"a":72,"key":"8:72","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَهَاجَرُوا۟ وَجَـٰهَدُوا۟ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ فِى سَبِيلِ ٱللَّهِ وَٱلَّذِينَ ءَاوَوا۟ وَّنَصَرُوٓا۟ أُو۟لَـٰٓئِكَ بَعْضُهُمْ أَوْلِيَآءُ بَعْضٍ ۚ وَٱلَّذِينَ ءَامَنُوا۟ وَلَمْ يُهَاجِرُوا۟ مَا لَكُم مِّن وَلَـٰيَتِهِم مِّن شَىْءٍ حَتَّىٰ يُهَاجِرُوا۟ ۚ وَإِنِ ٱسْتَنصَرُوكُمْ فِى ٱلدِّينِ فَعَلَيْكُمُ ٱلنَّصْرُ إِلَّا عَلَىٰ قَوْمٍۭ بَيْنَكُمْ وَبَيْنَهُم مِّيثَـٰقٌ ۗ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"Indeed, those who have believed and emigrated and fought with their wealth and lives in the cause of Allāh and those who gave shelter and aided - they are allies of one another. But those who believed and did not emigrate - for you there is no support of them until they emigrate. And if they seek help of you for the religion, then you must help, except against a people between yourselves and whom is a treaty. And Allāh is Seeing of what you do.","tr":"Inna allatheena amanoo wahajaroowajahadoo bi-amwalihim waanfusihim fee sabeeli Allahiwallatheena awaw wanasaroo ola-ikabaAAduhum awliyao baAAdin wallatheenaamanoo walam yuhajiroo ma lakum min walayatihimmin shay-in hatta yuhajiroo wa-ini istansarookumfee addeeni faAAalaykumu annasru illaAAala qawmin baynakum wabaynahum meethaqun wallahubima taAAmaloona baseer","juz":10,"page":186},{"s":8,"a":73,"key":"8:73","ar":"وَٱلَّذِينَ كَفَرُوا۟ بَعْضُهُمْ أَوْلِيَآءُ بَعْضٍ ۚ إِلَّا تَفْعَلُوهُ تَكُن فِتْنَةٌ فِى ٱلْأَرْضِ وَفَسَادٌ كَبِيرٌ","en":"And those who disbelieved are allies of one another. If you do not do so [i.e., ally yourselves with other believers], there will be fitnah [i.e., disbelief and oppression] on earth and great corruption.","tr":"Wallatheena kafaroo baAAduhumawliyao baAAdin illa tafAAaloohu takunfitnatun fee al-ardi wafasadun kabeer","juz":10,"page":186},{"s":8,"a":74,"key":"8:74","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَهَاجَرُوا۟ وَجَـٰهَدُوا۟ فِى سَبِيلِ ٱللَّهِ وَٱلَّذِينَ ءَاوَوا۟ وَّنَصَرُوٓا۟ أُو۟لَـٰٓئِكَ هُمُ ٱلْمُؤْمِنُونَ حَقًّا ۚ لَّهُم مَّغْفِرَةٌ وَرِزْقٌ كَرِيمٌ","en":"But those who have believed and emigrated and fought in the cause of Allāh and those who gave shelter and aided - it is they who are the believers, truly. For them is forgiveness and noble provision.","tr":"Wallatheena amanoo wahajaroowajahadoo fee sabeeli Allahi wallatheenaawaw wanasaroo ola-ika humu almu/minoona haqqanlahum maghfiratun warizqun kareem","juz":10,"page":186},{"s":8,"a":75,"key":"8:75","ar":"وَٱلَّذِينَ ءَامَنُوا۟ مِنۢ بَعْدُ وَهَاجَرُوا۟ وَجَـٰهَدُوا۟ مَعَكُمْ فَأُو۟لَـٰٓئِكَ مِنكُمْ ۚ وَأُو۟لُوا۟ ٱلْأَرْحَامِ بَعْضُهُمْ أَوْلَىٰ بِبَعْضٍ فِى كِتَـٰبِ ٱللَّهِ ۗ إِنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌۢ","en":"And those who believed after [the initial emigration] and emigrated and fought with you - they are of you. But those of [blood] relationship are more entitled [to inheritance] in the decree of Allāh.1 Indeed, Allāh is Knowing of all things.","tr":"Wallatheena amanoo minbaAAdu wahajaroo wajahadoo maAAakum faola-ikaminkum waoloo al-arhami baAAduhum awlabibaAAdin fee kitabi Allahi inna Allahabikulli shay-in AAaleem","juz":10,"page":186},{"s":9,"a":1,"key":"9:1","ar":"بَرَآءَةٌ مِّنَ ٱللَّهِ وَرَسُولِهِۦٓ إِلَى ٱلَّذِينَ عَـٰهَدتُّم مِّنَ ٱلْمُشْرِكِينَ","en":"[This is a declaration of] disassociation, from Allāh and His Messenger, to those with whom you had made a treaty among the polytheists.1","tr":"Baraatun mina Allahiwarasoolihi ila allatheena AAahadtum minaalmushrikeen","juz":10,"page":187},{"s":9,"a":2,"key":"9:2","ar":"فَسِيحُوا۟ فِى ٱلْأَرْضِ أَرْبَعَةَ أَشْهُرٍ وَٱعْلَمُوٓا۟ أَنَّكُمْ غَيْرُ مُعْجِزِى ٱللَّهِ ۙ وَأَنَّ ٱللَّهَ مُخْزِى ٱلْكَـٰفِرِينَ","en":"So travel freely, [O disbelievers], throughout the land [during] four months but know that you cannot cause failure to Allāh and that Allāh will disgrace the disbelievers.","tr":"Faseehoo fee al-ardi arbaAAataashhurin waAAlamoo annakum ghayru muAAjizee Allahiwaanna Allaha mukhzee alkafireen","juz":10,"page":187},{"s":9,"a":3,"key":"9:3","ar":"وَأَذَٰنٌ مِّنَ ٱللَّهِ وَرَسُولِهِۦٓ إِلَى ٱلنَّاسِ يَوْمَ ٱلْحَجِّ ٱلْأَكْبَرِ أَنَّ ٱللَّهَ بَرِىٓءٌ مِّنَ ٱلْمُشْرِكِينَ ۙ وَرَسُولُهُۥ ۚ فَإِن تُبْتُمْ فَهُوَ خَيْرٌ لَّكُمْ ۖ وَإِن تَوَلَّيْتُمْ فَٱعْلَمُوٓا۟ أَنَّكُمْ غَيْرُ مُعْجِزِى ٱللَّهِ ۗ وَبَشِّرِ ٱلَّذِينَ كَفَرُوا۟ بِعَذَابٍ أَلِيمٍ","en":"And [it is] an announcement from Allāh and His Messenger to the people on the day of the greater pilgrimage1 that Allāh is disassociated from the disbelievers, and [so is] His Messenger. So if you repent, that is best for you; but if you turn away - then know that you will not cause failure to Allāh.2 And give tidings to those who disbelieve of a painful punishment.","tr":"Waathanun mina Allahiwarasoolihi ila annasi yawma alhajjial-akbari anna Allaha baree-on mina almushrikeenawarasooluhu fa-in tubtum fahuwa khayrun lakum wa-in tawallaytumfaAAlamoo annakum ghayru muAAjizee Allahiwabashshiri allatheena kafaroo biAAathabin aleem","juz":10,"page":187},{"s":9,"a":4,"key":"9:4","ar":"إِلَّا ٱلَّذِينَ عَـٰهَدتُّم مِّنَ ٱلْمُشْرِكِينَ ثُمَّ لَمْ يَنقُصُوكُمْ شَيْـًٔا وَلَمْ يُظَـٰهِرُوا۟ عَلَيْكُمْ أَحَدًا فَأَتِمُّوٓا۟ إِلَيْهِمْ عَهْدَهُمْ إِلَىٰ مُدَّتِهِمْ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُتَّقِينَ","en":"Excepted are those with whom you made a treaty among the polytheists and then they have not been deficient toward you in anything or supported anyone against you; so complete for them their treaty until their term [has ended]. Indeed, Allāh loves the righteous [who fear Him].","tr":"Illa allatheena AAahadtummina almushrikeena thumma lam yanqusookum shay-an walam yuthahirooAAalaykum ahadan faatimmoo ilayhim AAahdahum ilamuddatihim inna Allaha yuhibbu almuttaqeen","juz":10,"page":187},{"s":9,"a":5,"key":"9:5","ar":"فَإِذَا ٱنسَلَخَ ٱلْأَشْهُرُ ٱلْحُرُمُ فَٱقْتُلُوا۟ ٱلْمُشْرِكِينَ حَيْثُ وَجَدتُّمُوهُمْ وَخُذُوهُمْ وَٱحْصُرُوهُمْ وَٱقْعُدُوا۟ لَهُمْ كُلَّ مَرْصَدٍ ۚ فَإِن تَابُوا۟ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَءَاتَوُا۟ ٱلزَّكَوٰةَ فَخَلُّوا۟ سَبِيلَهُمْ ۚ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"And when the inviolable months1 have passed, then kill the polytheists wherever you find them and capture them and besiege them and sit in wait for them at every place of ambush. But if they should repent, establish prayer, and give zakāh, let them [go] on their way. Indeed, Allāh is Forgiving and Merciful.","tr":"Fa-itha insalakha al-ashhuru alhurumufaqtuloo almushrikeena haythu wajadtumoohum wakhuthoohumwahsuroohum waqAAudoo lahum kulla marsadinfa-in taboo waaqamoo assalatawaatawoo azzakata fakhalloo sabeelahum innaAllaha ghafoorun raheem","juz":10,"page":187},{"s":9,"a":6,"key":"9:6","ar":"وَإِنْ أَحَدٌ مِّنَ ٱلْمُشْرِكِينَ ٱسْتَجَارَكَ فَأَجِرْهُ حَتَّىٰ يَسْمَعَ كَلَـٰمَ ٱللَّهِ ثُمَّ أَبْلِغْهُ مَأْمَنَهُۥ ۚ ذَٰلِكَ بِأَنَّهُمْ قَوْمٌ لَّا يَعْلَمُونَ","en":"And if any one of the polytheists seeks your protection, then grant him protection so that he may hear the words of Allāh [i.e., the Qur’ān]. Then deliver him to his place of safety. That is because they are a people who do not know.","tr":"Wa-in ahadun mina almushrikeena istajarakafaajirhu hatta yasmaAAa kalama Allahithumma ablighhu ma/manahu thalika bi-annahum qawmun layaAAlamoon","juz":10,"page":187},{"s":9,"a":7,"key":"9:7","ar":"كَيْفَ يَكُونُ لِلْمُشْرِكِينَ عَهْدٌ عِندَ ٱللَّهِ وَعِندَ رَسُولِهِۦٓ إِلَّا ٱلَّذِينَ عَـٰهَدتُّمْ عِندَ ٱلْمَسْجِدِ ٱلْحَرَامِ ۖ فَمَا ٱسْتَقَـٰمُوا۟ لَكُمْ فَٱسْتَقِيمُوا۟ لَهُمْ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُتَّقِينَ","en":"How can there be for the polytheists a treaty in the sight of Allāh and with His Messenger, except for those with whom you made a treaty at al-Masjid al-Ḥarām? So as long as they are upright toward you,1 be upright toward them. Indeed, Allāh loves the righteous [who fear Him].","tr":"Kayfa yakoonu lilmushrikeena AAahdun AAindaAllahi waAAinda rasoolihi illa allatheena AAahadtumAAinda almasjidi alharami fama istaqamoolakum fastaqeemoo lahum inna Allaha yuhibbualmuttaqeen","juz":10,"page":188},{"s":9,"a":8,"key":"9:8","ar":"كَيْفَ وَإِن يَظْهَرُوا۟ عَلَيْكُمْ لَا يَرْقُبُوا۟ فِيكُمْ إِلًّا وَلَا ذِمَّةً ۚ يُرْضُونَكُم بِأَفْوَٰهِهِمْ وَتَأْبَىٰ قُلُوبُهُمْ وَأَكْثَرُهُمْ فَـٰسِقُونَ","en":"How [can there be a treaty] while, if they gain dominance over you, they do not observe concerning you any pact of kinship or covenant of protection? They satisfy you with their mouths, but their hearts refuse [compliance], and most of them are defiantly disobedient.","tr":"Kayfa wa-in yathharoo AAalaykumla yarquboo feekum illan wala thimmatan yurdoonakumbi-afwahihim wata/ba quloobuhum waaktharuhum fasiqoon","juz":10,"page":188},{"s":9,"a":9,"key":"9:9","ar":"ٱشْتَرَوْا۟ بِـَٔايَـٰتِ ٱللَّهِ ثَمَنًا قَلِيلًا فَصَدُّوا۟ عَن سَبِيلِهِۦٓ ۚ إِنَّهُمْ سَآءَ مَا كَانُوا۟ يَعْمَلُونَ","en":"They have exchanged the signs of Allāh for a small price and averted [people] from His way. Indeed, it was evil that they were doing.","tr":"Ishtaraw bi-ayati Allahithamanan qaleelan fasaddoo AAan sabeelihi innahum saama kanoo yaAAmaloon","juz":10,"page":188},{"s":9,"a":10,"key":"9:10","ar":"لَا يَرْقُبُونَ فِى مُؤْمِنٍ إِلًّا وَلَا ذِمَّةً ۚ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُعْتَدُونَ","en":"They do not observe toward a believer any pact of kinship or covenant of protection. And it is they who are the transgressors.","tr":"La yarquboona fee mu/minin illan walathimmatan waola-ika humu almuAAtadoon","juz":10,"page":188},{"s":9,"a":11,"key":"9:11","ar":"فَإِن تَابُوا۟ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَءَاتَوُا۟ ٱلزَّكَوٰةَ فَإِخْوَٰنُكُمْ فِى ٱلدِّينِ ۗ وَنُفَصِّلُ ٱلْـَٔايَـٰتِ لِقَوْمٍ يَعْلَمُونَ","en":"But if they repent, establish prayer, and give zakāh, then they are your brothers in religion; and We detail the verses for a people who know.","tr":"Fa-in taboo waaqamoo assalatawaatawoo azzakata fa-ikhwanukum feeaddeeni wanufassilu al-ayatiliqawmin yaAAlamoon","juz":10,"page":188},{"s":9,"a":12,"key":"9:12","ar":"وَإِن نَّكَثُوٓا۟ أَيْمَـٰنَهُم مِّنۢ بَعْدِ عَهْدِهِمْ وَطَعَنُوا۟ فِى دِينِكُمْ فَقَـٰتِلُوٓا۟ أَئِمَّةَ ٱلْكُفْرِ ۙ إِنَّهُمْ لَآ أَيْمَـٰنَ لَهُمْ لَعَلَّهُمْ يَنتَهُونَ","en":"And if they break their oaths after their treaty and defame your religion, then combat the leaders of disbelief, for indeed, there are no oaths [sacred] to them; [fight them that] they might cease.","tr":"Wa-in nakathoo aymanahum min baAAdiAAahdihim wataAAanoo fee deenikum faqatilooa-immata alkufri innahum la aymana lahumlaAAallahum yantahoon","juz":10,"page":188},{"s":9,"a":13,"key":"9:13","ar":"أَلَا تُقَـٰتِلُونَ قَوْمًا نَّكَثُوٓا۟ أَيْمَـٰنَهُمْ وَهَمُّوا۟ بِإِخْرَاجِ ٱلرَّسُولِ وَهُم بَدَءُوكُمْ أَوَّلَ مَرَّةٍ ۚ أَتَخْشَوْنَهُمْ ۚ فَٱللَّهُ أَحَقُّ أَن تَخْشَوْهُ إِن كُنتُم مُّؤْمِنِينَ","en":"Would you not fight against a people who broke their oaths and determined to expel the Messenger, and they had begun [the attack upon] you the first time? Do you fear them? But Allāh has more right that you should fear Him, if you are [truly] believers.","tr":"Ala tuqatiloona qawmannakathoo aymanahum wahammoo bi-ikhraji arrasooliwahum badaookum awwala marratin atakhshawnahum fallahuahaqqu an takhshawhu in kuntum mu/mineen","juz":10,"page":188},{"s":9,"a":14,"key":"9:14","ar":"قَـٰتِلُوهُمْ يُعَذِّبْهُمُ ٱللَّهُ بِأَيْدِيكُمْ وَيُخْزِهِمْ وَيَنصُرْكُمْ عَلَيْهِمْ وَيَشْفِ صُدُورَ قَوْمٍ مُّؤْمِنِينَ","en":"Fight them; Allāh will punish them by your hands and will disgrace them and give you victory over them and satisfy the breasts [i.e., desires] of a believing people","tr":"Qatiloohum yuAAaththibhumu Allahubi-aydeekum wayukhzihim wayansurkum AAalayhim wayashfi sudooraqawmin mu/mineen","juz":10,"page":189},{"s":9,"a":15,"key":"9:15","ar":"وَيُذْهِبْ غَيْظَ قُلُوبِهِمْ ۗ وَيَتُوبُ ٱللَّهُ عَلَىٰ مَن يَشَآءُ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"And remove the fury in their [i.e., the believers'] hearts. And Allāh turns in forgiveness to whom He wills; and Allāh is Knowing and Wise.","tr":"Wayuthhib ghaythaquloobihim wayatoobu Allahu AAala man yashaowallahu AAaleemun hakeem","juz":10,"page":189},{"s":9,"a":16,"key":"9:16","ar":"أَمْ حَسِبْتُمْ أَن تُتْرَكُوا۟ وَلَمَّا يَعْلَمِ ٱللَّهُ ٱلَّذِينَ جَـٰهَدُوا۟ مِنكُمْ وَلَمْ يَتَّخِذُوا۟ مِن دُونِ ٱللَّهِ وَلَا رَسُولِهِۦ وَلَا ٱلْمُؤْمِنِينَ وَلِيجَةً ۚ وَٱللَّهُ خَبِيرٌۢ بِمَا تَعْمَلُونَ","en":"Do you think that you will be left [as you are] while Allāh has not yet made evident those among you who strive [for His cause] and do not take other than Allāh, His Messenger and the believers as intimates? And Allāh is [fully] Aware of what you do.","tr":"Am hasibtum an tutrakoo walammayaAAlami Allahu allatheena jahadoo minkumwalam yattakhithoo min dooni Allahi walarasoolihi wala almu/mineena waleejatan wallahukhabeerun bima taAAmaloon","juz":10,"page":189},{"s":9,"a":17,"key":"9:17","ar":"مَا كَانَ لِلْمُشْرِكِينَ أَن يَعْمُرُوا۟ مَسَـٰجِدَ ٱللَّهِ شَـٰهِدِينَ عَلَىٰٓ أَنفُسِهِم بِٱلْكُفْرِ ۚ أُو۟لَـٰٓئِكَ حَبِطَتْ أَعْمَـٰلُهُمْ وَفِى ٱلنَّارِ هُمْ خَـٰلِدُونَ","en":"It is not for the polytheists to maintain the mosques of Allāh [while] witnessing against themselves with disbelief. [For] those, their deeds have become worthless, and in the Fire they will abide eternally.","tr":"Ma kana lilmushrikeena anyaAAmuroo masajida Allahi shahideena AAalaanfusihim bilkufri ola-ika habitataAAmaluhum wafee annari hum khalidoon","juz":10,"page":189},{"s":9,"a":18,"key":"9:18","ar":"إِنَّمَا يَعْمُرُ مَسَـٰجِدَ ٱللَّهِ مَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ وَأَقَامَ ٱلصَّلَوٰةَ وَءَاتَى ٱلزَّكَوٰةَ وَلَمْ يَخْشَ إِلَّا ٱللَّهَ ۖ فَعَسَىٰٓ أُو۟لَـٰٓئِكَ أَن يَكُونُوا۟ مِنَ ٱلْمُهْتَدِينَ","en":"The mosques of Allāh are only to be maintained by those who believe in Allāh and the Last Day and establish prayer and give zakāh and do not fear except Allāh, for it is expected that those will be of the [rightly] guided.","tr":"Innama yaAAmuru masajida Allahiman amana billahi walyawmi al-akhiriwaaqama assalata waataazzakata walam yakhsha illa AllahafaAAasa ola-ika an yakoonoo mina almuhtadeen","juz":10,"page":189},{"s":9,"a":19,"key":"9:19","ar":"۞ أَجَعَلْتُمْ سِقَايَةَ ٱلْحَآجِّ وَعِمَارَةَ ٱلْمَسْجِدِ ٱلْحَرَامِ كَمَنْ ءَامَنَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ وَجَـٰهَدَ فِى سَبِيلِ ٱللَّهِ ۚ لَا يَسْتَوُۥنَ عِندَ ٱللَّهِ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"Have you made the providing of water for the pilgrim and the maintenance of al-Masjid al-Ḥarām equal to [the deeds of] one who believes in Allāh and the Last Day and strives in the cause of Allāh? They are not equal in the sight of Allāh. And Allāh does not guide the wrongdoing people.","tr":"AjaAAaltum siqayata alhajjiwaAAimarata almasjidi alharami kaman amanabillahi walyawmi al-akhiri wajahadafee sabeeli Allahi la yastawoona AAinda Allahiwallahu la yahdee alqawma aththalimeen","juz":10,"page":189},{"s":9,"a":20,"key":"9:20","ar":"ٱلَّذِينَ ءَامَنُوا۟ وَهَاجَرُوا۟ وَجَـٰهَدُوا۟ فِى سَبِيلِ ٱللَّهِ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ أَعْظَمُ دَرَجَةً عِندَ ٱللَّهِ ۚ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْفَآئِزُونَ","en":"The ones who have believed, emigrated and striven in the cause of Allāh with their wealth and their lives are greater in rank in the sight of Allāh. And it is those who are the attainers [of success].","tr":"Allatheena amanoo wahajaroowajahadoo fee sabeeli Allahi bi-amwalihimwaanfusihim aAAthamu darajatan AAinda Allahiwaola-ika humu alfa-izoon","juz":10,"page":189},{"s":9,"a":21,"key":"9:21","ar":"يُبَشِّرُهُمْ رَبُّهُم بِرَحْمَةٍ مِّنْهُ وَرِضْوَٰنٍ وَجَنَّـٰتٍ لَّهُمْ فِيهَا نَعِيمٌ مُّقِيمٌ","en":"Their Lord gives them good tidings of mercy from Him and approval and of gardens for them wherein is enduring pleasure.","tr":"Yubashshiruhum rabbuhum birahmatinminhu waridwanin wajannatin lahum feehanaAAeemun muqeem","juz":10,"page":190},{"s":9,"a":22,"key":"9:22","ar":"خَـٰلِدِينَ فِيهَآ أَبَدًا ۚ إِنَّ ٱللَّهَ عِندَهُۥٓ أَجْرٌ عَظِيمٌ","en":"[They will be] abiding therein forever. Indeed, Allāh has with Him a great reward.","tr":"Khalideena feeha abadan innaAllaha AAindahu ajrun AAatheem","juz":10,"page":190},{"s":9,"a":23,"key":"9:23","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوٓا۟ ءَابَآءَكُمْ وَإِخْوَٰنَكُمْ أَوْلِيَآءَ إِنِ ٱسْتَحَبُّوا۟ ٱلْكُفْرَ عَلَى ٱلْإِيمَـٰنِ ۚ وَمَن يَتَوَلَّهُم مِّنكُمْ فَأُو۟لَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ","en":"O you who have believed, do not take your fathers or your brothers as allies if they have preferred disbelief over belief. And whoever does so among you - then it is those who are the wrongdoers.","tr":"Ya ayyuha allatheena amanoola tattakhithoo abaakum wa-ikhwanakumawliyaa ini istahabboo alkufra AAala al-eemaniwaman yatawallahum minkum faola-ika humu aththalimoon","juz":10,"page":190},{"s":9,"a":24,"key":"9:24","ar":"قُلْ إِن كَانَ ءَابَآؤُكُمْ وَأَبْنَآؤُكُمْ وَإِخْوَٰنُكُمْ وَأَزْوَٰجُكُمْ وَعَشِيرَتُكُمْ وَأَمْوَٰلٌ ٱقْتَرَفْتُمُوهَا وَتِجَـٰرَةٌ تَخْشَوْنَ كَسَادَهَا وَمَسَـٰكِنُ تَرْضَوْنَهَآ أَحَبَّ إِلَيْكُم مِّنَ ٱللَّهِ وَرَسُولِهِۦ وَجِهَادٍ فِى سَبِيلِهِۦ فَتَرَبَّصُوا۟ حَتَّىٰ يَأْتِىَ ٱللَّهُ بِأَمْرِهِۦ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلْفَـٰسِقِينَ","en":"Say, [O Muḥammad], \"If your fathers, your sons, your brothers, your wives, your relatives, wealth which you have obtained, commerce wherein you fear decline, and dwellings with which you are pleased are more beloved to you than Allāh and His Messenger and jihād [i.e., striving] in His cause, then wait until Allāh executes His command. And Allāh does not guide the defiantly disobedient people.\"","tr":"Qul in kana abaokumwaabnaokum wa-ikhwanukum waazwajukumwaAAasheeratukum waamwalun iqtaraftumooha watijaratuntakhshawna kasadaha wamasakinu tardawnahaahabba ilaykum mina Allahi warasoolihi wajihadinfee sabeelihi fatarabbasoo hatta ya/tiya Allahubi-amrihi wallahu la yahdee alqawma alfasiqeen","juz":10,"page":190},{"s":9,"a":25,"key":"9:25","ar":"لَقَدْ نَصَرَكُمُ ٱللَّهُ فِى مَوَاطِنَ كَثِيرَةٍ ۙ وَيَوْمَ حُنَيْنٍ ۙ إِذْ أَعْجَبَتْكُمْ كَثْرَتُكُمْ فَلَمْ تُغْنِ عَنكُمْ شَيْـًٔا وَضَاقَتْ عَلَيْكُمُ ٱلْأَرْضُ بِمَا رَحُبَتْ ثُمَّ وَلَّيْتُم مُّدْبِرِينَ","en":"Allāh has already given you victory in many regions and [even] on the day of Ḥunayn, when your great number pleased you, but it did not avail you at all, and the earth was confining for you with [i.e., in spite of] its vastness; then you turned back, fleeing.","tr":"Laqad nasarakumu Allahu feemawatina katheeratin wayawma hunaynin ithaAAjabatkum kathratukum falam tughni AAankum shay-an wadaqatAAalaykumu al-ardu bima rahubat thummawallaytum mudbireen","juz":10,"page":190},{"s":9,"a":26,"key":"9:26","ar":"ثُمَّ أَنزَلَ ٱللَّهُ سَكِينَتَهُۥ عَلَىٰ رَسُولِهِۦ وَعَلَى ٱلْمُؤْمِنِينَ وَأَنزَلَ جُنُودًا لَّمْ تَرَوْهَا وَعَذَّبَ ٱلَّذِينَ كَفَرُوا۟ ۚ وَذَٰلِكَ جَزَآءُ ٱلْكَـٰفِرِينَ","en":"Then Allāh sent down His tranquility upon His Messenger and upon the believers and sent down soldiers [i.e., angels] whom you did not see and punished those who disbelieved. And that is the recompense of the disbelievers.","tr":"Thumma anzala Allahu sakeenatahu AAalarasoolihi waAAala almu/mineena waanzala junoodan lamtarawha waAAaththaba allatheena kafaroo wathalikajazao alkafireen","juz":10,"page":190},{"s":9,"a":27,"key":"9:27","ar":"ثُمَّ يَتُوبُ ٱللَّهُ مِنۢ بَعْدِ ذَٰلِكَ عَلَىٰ مَن يَشَآءُ ۗ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"Then Allāh will accept repentance after that for whom He wills; and Allāh is Forgiving and Merciful.","tr":"Thumma yatoobu Allahu min baAAdi thalikaAAala man yashao wallahu ghafoorunraheem","juz":10,"page":191},{"s":9,"a":28,"key":"9:28","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّمَا ٱلْمُشْرِكُونَ نَجَسٌ فَلَا يَقْرَبُوا۟ ٱلْمَسْجِدَ ٱلْحَرَامَ بَعْدَ عَامِهِمْ هَـٰذَا ۚ وَإِنْ خِفْتُمْ عَيْلَةً فَسَوْفَ يُغْنِيكُمُ ٱللَّهُ مِن فَضْلِهِۦٓ إِن شَآءَ ۚ إِنَّ ٱللَّهَ عَلِيمٌ حَكِيمٌ","en":"O you who have believed, indeed the polytheists are unclean, so let them not approach al-Masjid al-Ḥarām after this, their [final] year. And if you fear privation, Allāh will enrich you from His bounty if He wills. Indeed, Allāh is Knowing and Wise.","tr":"Ya ayyuha allatheena amanooinnama almushrikoona najasun fala yaqrabooalmasjida alharama baAAda AAamihim hathawa-in khiftum AAaylatan fasawfa yughneekumu Allahu min fadlihiin shaa inna Allaha AAaleemun hakeem","juz":10,"page":191},{"s":9,"a":29,"key":"9:29","ar":"قَـٰتِلُوا۟ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱللَّهِ وَلَا بِٱلْيَوْمِ ٱلْـَٔاخِرِ وَلَا يُحَرِّمُونَ مَا حَرَّمَ ٱللَّهُ وَرَسُولُهُۥ وَلَا يَدِينُونَ دِينَ ٱلْحَقِّ مِنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ حَتَّىٰ يُعْطُوا۟ ٱلْجِزْيَةَ عَن يَدٍ وَهُمْ صَـٰغِرُونَ","en":"Fight against those who do not believe in Allāh or in the Last Day and who do not consider unlawful what Allāh and His Messenger have made unlawful and who do not adopt the religion of truth [i.e., Islām] from those who were given the Scripture - [fight] until they give the jizyah1 willingly while they are humbled.","tr":"Qatiloo allatheena layu/minoona billahi wala bilyawmial-akhiri wala yuharrimoona ma harramaAllahu warasooluhu wala yadeenoona deena alhaqqimina allatheena ootoo alkitaba hattayuAAtoo aljizyata AAan yadin wahum saghiroon","juz":10,"page":191},{"s":9,"a":30,"key":"9:30","ar":"وَقَالَتِ ٱلْيَهُودُ عُزَيْرٌ ٱبْنُ ٱللَّهِ وَقَالَتِ ٱلنَّصَـٰرَى ٱلْمَسِيحُ ٱبْنُ ٱللَّهِ ۖ ذَٰلِكَ قَوْلُهُم بِأَفْوَٰهِهِمْ ۖ يُضَـٰهِـُٔونَ قَوْلَ ٱلَّذِينَ كَفَرُوا۟ مِن قَبْلُ ۚ قَـٰتَلَهُمُ ٱللَّهُ ۚ أَنَّىٰ يُؤْفَكُونَ","en":"The Jews say, \"Ezra is the son of Allāh\"; and the Christians say, \"The Messiah is the son of Allāh.\" That is their statement from their mouths; they imitate the saying of those who disbelieved before [them]. May Allāh destroy them; how are they deluded?","tr":"Waqalati alyahoodu AAuzayrun ibnu Allahiwaqalati annasara almaseehuibnu Allahi thalika qawluhum bi-afwahihim yudahi-oonaqawla allatheena kafaroo min qablu qatalahumu Allahuanna yu/fakoon","juz":10,"page":191},{"s":9,"a":31,"key":"9:31","ar":"ٱتَّخَذُوٓا۟ أَحْبَارَهُمْ وَرُهْبَـٰنَهُمْ أَرْبَابًا مِّن دُونِ ٱللَّهِ وَٱلْمَسِيحَ ٱبْنَ مَرْيَمَ وَمَآ أُمِرُوٓا۟ إِلَّا لِيَعْبُدُوٓا۟ إِلَـٰهًا وَٰحِدًا ۖ لَّآ إِلَـٰهَ إِلَّا هُوَ ۚ سُبْحَـٰنَهُۥ عَمَّا يُشْرِكُونَ","en":"They have taken their scholars and monks as lords besides Allāh,1 and [also] the Messiah, the son of Mary.2 And they were not commanded except to worship one God; there is no deity except Him. Exalted is He above whatever they associate with Him.","tr":"Ittakhathoo ahbarahumwaruhbanahum arbaban min dooni Allahi walmaseehaibna maryama wama omiroo illa liyaAAbudoo ilahanwahidan la ilaha illa huwa subhanahuAAamma yushrikoon","juz":10,"page":191},{"s":9,"a":32,"key":"9:32","ar":"يُرِيدُونَ أَن يُطْفِـُٔوا۟ نُورَ ٱللَّهِ بِأَفْوَٰهِهِمْ وَيَأْبَى ٱللَّهُ إِلَّآ أَن يُتِمَّ نُورَهُۥ وَلَوْ كَرِهَ ٱلْكَـٰفِرُونَ","en":"They want to extinguish the light of Allāh with their mouths, but Allāh refuses except to perfect His light, although the disbelievers dislike it.","tr":"Yureedoona an yutfi-oo noora Allahibi-afwahihim waya/ba Allahu illa anyutimma noorahu walaw kariha alkafiroon","juz":10,"page":192},{"s":9,"a":33,"key":"9:33","ar":"هُوَ ٱلَّذِىٓ أَرْسَلَ رَسُولَهُۥ بِٱلْهُدَىٰ وَدِينِ ٱلْحَقِّ لِيُظْهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ وَلَوْ كَرِهَ ٱلْمُشْرِكُونَ","en":"It is He who has sent His Messenger with guidance and the religion of truth to manifest it over all religion, although they who associate others with Allāh dislike it.","tr":"Huwa allathee arsala rasoolahu bilhudawadeeni alhaqqi liyuthhirahu AAala addeenikullihi walaw kariha almushrikoon","juz":10,"page":192},{"s":9,"a":34,"key":"9:34","ar":"۞ يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ كَثِيرًا مِّنَ ٱلْأَحْبَارِ وَٱلرُّهْبَانِ لَيَأْكُلُونَ أَمْوَٰلَ ٱلنَّاسِ بِٱلْبَـٰطِلِ وَيَصُدُّونَ عَن سَبِيلِ ٱللَّهِ ۗ وَٱلَّذِينَ يَكْنِزُونَ ٱلذَّهَبَ وَٱلْفِضَّةَ وَلَا يُنفِقُونَهَا فِى سَبِيلِ ٱللَّهِ فَبَشِّرْهُم بِعَذَابٍ أَلِيمٍ","en":"O you who have believed, indeed many of the scholars and the monks devour the wealth of people unjustly1 and avert [them] from the way of Allāh. And those who hoard gold and silver and spend it not in the way of Allāh - give them tidings of a painful punishment.","tr":"Ya ayyuha allatheena amanooinna katheeran mina al-ahbari warruhbanilaya/kuloona amwala annasi bilbatiliwayasuddoona AAan sabeeli Allahi wallatheenayaknizoona aththahaba walfiddatawala yunfiqoonaha fee sabeeli Allahifabashshirhum biAAathabin aleem","juz":10,"page":192},{"s":9,"a":35,"key":"9:35","ar":"يَوْمَ يُحْمَىٰ عَلَيْهَا فِى نَارِ جَهَنَّمَ فَتُكْوَىٰ بِهَا جِبَاهُهُمْ وَجُنُوبُهُمْ وَظُهُورُهُمْ ۖ هَـٰذَا مَا كَنَزْتُمْ لِأَنفُسِكُمْ فَذُوقُوا۟ مَا كُنتُمْ تَكْنِزُونَ","en":"The Day when it1 will be heated in the fire of Hell and seared therewith will be their foreheads, their flanks, and their backs, [it will be said], \"This is what you hoarded for yourselves, so taste what you used to hoard.\"","tr":"Yawma yuhma AAalayhafee nari jahannama fatukwa biha jibahuhumwajunoobuhum wathuhooruhum hatha makanaztum li-anfusikum fathooqoo ma kuntum taknizoon","juz":10,"page":192},{"s":9,"a":36,"key":"9:36","ar":"إِنَّ عِدَّةَ ٱلشُّهُورِ عِندَ ٱللَّهِ ٱثْنَا عَشَرَ شَهْرًا فِى كِتَـٰبِ ٱللَّهِ يَوْمَ خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ مِنْهَآ أَرْبَعَةٌ حُرُمٌ ۚ ذَٰلِكَ ٱلدِّينُ ٱلْقَيِّمُ ۚ فَلَا تَظْلِمُوا۟ فِيهِنَّ أَنفُسَكُمْ ۚ وَقَـٰتِلُوا۟ ٱلْمُشْرِكِينَ كَآفَّةً كَمَا يُقَـٰتِلُونَكُمْ كَآفَّةً ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ مَعَ ٱلْمُتَّقِينَ","en":"Indeed, the number of months with Allāh is twelve [lunar] months in the register of Allāh [from] the day He created the heavens and the earth; of these, four are sacred.1 That is the correct religion [i.e., way], so do not wrong yourselves during them.2 And fight against the disbelievers collectively as they fight against you collectively. And know that Allāh is with the righteous [who fear Him].","tr":"Inna AAiddata ashshuhoori AAinda Allahiithna AAashara shahran fee kitabi Allahiyawma khalaqa assamawati wal-ardaminha arbaAAatun hurumun thalika addeenualqayyimu fala tathlimoo feehinna anfusakumwaqatiloo almushrikeena kaffatan kama yuqatiloonakumkaffatan waAAlamoo anna Allaha maAAaalmuttaqeen","juz":10,"page":192},{"s":9,"a":37,"key":"9:37","ar":"إِنَّمَا ٱلنَّسِىٓءُ زِيَادَةٌ فِى ٱلْكُفْرِ ۖ يُضَلُّ بِهِ ٱلَّذِينَ كَفَرُوا۟ يُحِلُّونَهُۥ عَامًا وَيُحَرِّمُونَهُۥ عَامًا لِّيُوَاطِـُٔوا۟ عِدَّةَ مَا حَرَّمَ ٱللَّهُ فَيُحِلُّوا۟ مَا حَرَّمَ ٱللَّهُ ۚ زُيِّنَ لَهُمْ سُوٓءُ أَعْمَـٰلِهِمْ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلْكَـٰفِرِينَ","en":"Indeed, the postponing [of restriction within sacred months] is an increase in disbelief by which those who have disbelieved are led [further] astray. They make it1 lawful one year and unlawful another year to correspond to the number made unlawful by Allāh2 and [thus] make lawful what Allāh has made unlawful. Made pleasing to them is the evil of their deeds; and Allāh does not guide the disbelieving people.","tr":"Innama annasee-o ziyadatunfee alkufri yudallu bihi allatheena kafaroo yuhilloonahuAAaman wayuharrimoonahu AAaman liyuwati-ooAAiddata ma harrama Allahu fayuhillooma harrama Allahu zuyyina lahum soo-o aAAmalihimwallahu la yahdee alqawma alkafireen","juz":10,"page":193},{"s":9,"a":38,"key":"9:38","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ مَا لَكُمْ إِذَا قِيلَ لَكُمُ ٱنفِرُوا۟ فِى سَبِيلِ ٱللَّهِ ٱثَّاقَلْتُمْ إِلَى ٱلْأَرْضِ ۚ أَرَضِيتُم بِٱلْحَيَوٰةِ ٱلدُّنْيَا مِنَ ٱلْـَٔاخِرَةِ ۚ فَمَا مَتَـٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا فِى ٱلْـَٔاخِرَةِ إِلَّا قَلِيلٌ","en":"O you who have believed, what is [the matter] with you that, when you are told to go forth in the cause of Allāh, you adhere heavily to the earth?1 Are you satisfied with the life of this world rather than the Hereafter? But what is the enjoyment of worldly life compared to the Hereafter except a [very] little.","tr":"Ya ayyuha allatheena amanooma lakum itha qeela lakumu infiroo fee sabeeli Allahiiththaqaltum ila al-ardi aradeetum bilhayatiaddunya mina al-akhirati fama mataAAualhayati addunya fee al-akhiratiilla qaleel","juz":10,"page":193},{"s":9,"a":39,"key":"9:39","ar":"إِلَّا تَنفِرُوا۟ يُعَذِّبْكُمْ عَذَابًا أَلِيمًا وَيَسْتَبْدِلْ قَوْمًا غَيْرَكُمْ وَلَا تَضُرُّوهُ شَيْـًٔا ۗ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"If you do not go forth, He will punish you with a painful punishment and will replace you with another people, and you will not harm Him at all. And Allāh is over all things competent.","tr":"Illa tanfiroo yuAAaththibkumAAathaban aleeman wayastabdil qawman ghayrakum walatadurroohu shay-an wallahu AAalakulli shay-in qadeer","juz":10,"page":193},{"s":9,"a":40,"key":"9:40","ar":"إِلَّا تَنصُرُوهُ فَقَدْ نَصَرَهُ ٱللَّهُ إِذْ أَخْرَجَهُ ٱلَّذِينَ كَفَرُوا۟ ثَانِىَ ٱثْنَيْنِ إِذْ هُمَا فِى ٱلْغَارِ إِذْ يَقُولُ لِصَـٰحِبِهِۦ لَا تَحْزَنْ إِنَّ ٱللَّهَ مَعَنَا ۖ فَأَنزَلَ ٱللَّهُ سَكِينَتَهُۥ عَلَيْهِ وَأَيَّدَهُۥ بِجُنُودٍ لَّمْ تَرَوْهَا وَجَعَلَ كَلِمَةَ ٱلَّذِينَ كَفَرُوا۟ ٱلسُّفْلَىٰ ۗ وَكَلِمَةُ ٱللَّهِ هِىَ ٱلْعُلْيَا ۗ وَٱللَّهُ عَزِيزٌ حَكِيمٌ","en":"If you do not aid him [i.e., the Prophet (ﷺ)] - Allāh has already aided him when those who disbelieved had driven him out [of Makkah] as one of two,1 when they were in the cave and he [i.e., Muḥammad (ﷺ)] said to his companion, \"Do not grieve; indeed Allāh is with us.\" And Allāh sent down His tranquility upon him and supported him with soldiers [i.e., angels] you did not see and made the word2 of those who disbelieved the lowest,3 while the word of Allāh4 - that is the highest. And Allāh is Exalted in Might and Wise.","tr":"Illa tansuroohu faqad nasarahuAllahu ith akhrajahu allatheena kafaroo thaniyaithnayni ith huma fee alghari ithyaqoolu lisahibihi la tahzan inna AllahamaAAana faanzala Allahu sakeenatahu AAalayhiwaayyadahu bijunoodin lam tarawha wajaAAala kalimata allatheenakafaroo assufla wakalimatu Allahi hiyaalAAulya wallahu AAazeezun hakeem","juz":10,"page":193},{"s":9,"a":41,"key":"9:41","ar":"ٱنفِرُوا۟ خِفَافًا وَثِقَالًا وَجَـٰهِدُوا۟ بِأَمْوَٰلِكُمْ وَأَنفُسِكُمْ فِى سَبِيلِ ٱللَّهِ ۚ ذَٰلِكُمْ خَيْرٌ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ","en":"Go forth, whether light or heavy,1 and strive with your wealth and your lives in the cause of Allāh. That is better for you, if you only knew.","tr":"Infiroo khifafan wathiqalanwajahidoo bi-amwalikum waanfusikum fee sabeeli Allahithalikum khayrun lakum in kuntum taAAlamoon","juz":10,"page":194},{"s":9,"a":42,"key":"9:42","ar":"لَوْ كَانَ عَرَضًا قَرِيبًا وَسَفَرًا قَاصِدًا لَّٱتَّبَعُوكَ وَلَـٰكِنۢ بَعُدَتْ عَلَيْهِمُ ٱلشُّقَّةُ ۚ وَسَيَحْلِفُونَ بِٱللَّهِ لَوِ ٱسْتَطَعْنَا لَخَرَجْنَا مَعَكُمْ يُهْلِكُونَ أَنفُسَهُمْ وَٱللَّهُ يَعْلَمُ إِنَّهُمْ لَكَـٰذِبُونَ","en":"Had it been a near [i.e., easy] gain and a moderate trip, they [i.e., the hypocrites] would have followed you, but distant to them was the journey. And they will swear by Allāh,1 \"If we were able, we would have gone forth with you,\" destroying themselves [through false oaths], and Allāh knows that indeed they are liars.","tr":"Law kana AAaradan qareebanwasafaran qasidan lattabaAAooka walakinbaAAudat AAalayhimu ashshuqqatu wasayahlifoona billahilawi istataAAna lakharajna maAAakumyuhlikoona anfusahum wallahu yaAAlamu innahum lakathiboon","juz":10,"page":194},{"s":9,"a":43,"key":"9:43","ar":"عَفَا ٱللَّهُ عَنكَ لِمَ أَذِنتَ لَهُمْ حَتَّىٰ يَتَبَيَّنَ لَكَ ٱلَّذِينَ صَدَقُوا۟ وَتَعْلَمَ ٱلْكَـٰذِبِينَ","en":"Allāh has pardoned you, [O Muḥammad, but] why did you give them permission [to remain behind]? [You should not have] until it was evident to you who were truthful and you knew [who were] the liars.","tr":"AAafa Allahu AAanka lima athintalahum hatta yatabayyana laka allatheena sadaqoowataAAlama alkathibeen","juz":10,"page":194},{"s":9,"a":44,"key":"9:44","ar":"لَا يَسْتَـْٔذِنُكَ ٱلَّذِينَ يُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ أَن يُجَـٰهِدُوا۟ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلْمُتَّقِينَ","en":"Those who believe in Allāh and the Last Day would not ask permission of you to be excused from striving [i.e., fighting] with their wealth and their lives. And Allāh is Knowing of those who fear Him.","tr":"La yasta/thinuka allatheenayu/minoona billahi walyawmi al-akhirian yujahidoo bi-amwalihim waanfusihim wallahuAAaleemun bilmuttaqeen","juz":10,"page":194},{"s":9,"a":45,"key":"9:45","ar":"إِنَّمَا يَسْتَـْٔذِنُكَ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ وَٱرْتَابَتْ قُلُوبُهُمْ فَهُمْ فِى رَيْبِهِمْ يَتَرَدَّدُونَ","en":"Only those would ask permission of you who do not believe in Allāh and the Last Day and whose hearts have doubted, and they, in their doubt, are hesitating.","tr":"Innama yasta/thinuka allatheenala yu/minoona billahi walyawmi al-akhiriwartabat quloobuhum fahum fee raybihimyataraddadoon","juz":10,"page":194},{"s":9,"a":46,"key":"9:46","ar":"۞ وَلَوْ أَرَادُوا۟ ٱلْخُرُوجَ لَأَعَدُّوا۟ لَهُۥ عُدَّةً وَلَـٰكِن كَرِهَ ٱللَّهُ ٱنۢبِعَاثَهُمْ فَثَبَّطَهُمْ وَقِيلَ ٱقْعُدُوا۟ مَعَ ٱلْقَـٰعِدِينَ","en":"And if they had intended to go forth, they would have prepared for it [some] preparation. But Allāh disliked their being sent, so He kept them back, and they were told, \"Remain [behind] with those who remain.\"1","tr":"Walaw aradoo alkhurooja laaAAaddoolahu AAuddatan walakin kariha Allahu inbiAAathahumfathabbatahum waqeela oqAAudoo maAAa alqaAAideen","juz":10,"page":194},{"s":9,"a":47,"key":"9:47","ar":"لَوْ خَرَجُوا۟ فِيكُم مَّا زَادُوكُمْ إِلَّا خَبَالًا وَلَأَوْضَعُوا۟ خِلَـٰلَكُمْ يَبْغُونَكُمُ ٱلْفِتْنَةَ وَفِيكُمْ سَمَّـٰعُونَ لَهُمْ ۗ وَٱللَّهُ عَلِيمٌۢ بِٱلظَّـٰلِمِينَ","en":"Had they gone forth with you, they would not have increased you except in confusion, and they would have been active among you, seeking [to cause] you fitnah [i.e., chaos and dissension]. And among you are avid listeners to them. And Allāh is Knowing of the wrongdoers.","tr":"Law kharajoo feekum ma zadookumilla khabalan walaawdaAAoo khilalakumyabghoonakumu alfitnata wafeekum sammaAAoona lahum wallahuAAaleemun biththalimeen","juz":10,"page":194},{"s":9,"a":48,"key":"9:48","ar":"لَقَدِ ٱبْتَغَوُا۟ ٱلْفِتْنَةَ مِن قَبْلُ وَقَلَّبُوا۟ لَكَ ٱلْأُمُورَ حَتَّىٰ جَآءَ ٱلْحَقُّ وَظَهَرَ أَمْرُ ٱللَّهِ وَهُمْ كَـٰرِهُونَ","en":"They had already desired dissension before and had upset matters for you1 until the truth came and the ordinance [i.e., victory] of Allāh appeared, while they were averse.","tr":"Laqadi ibtaghawoo alfitnata min qabluwaqallaboo laka al-omoora hatta jaa alhaqquwathahara amru Allahi wahum karihoon","juz":10,"page":195},{"s":9,"a":49,"key":"9:49","ar":"وَمِنْهُم مَّن يَقُولُ ٱئْذَن لِّى وَلَا تَفْتِنِّىٓ ۚ أَلَا فِى ٱلْفِتْنَةِ سَقَطُوا۟ ۗ وَإِنَّ جَهَنَّمَ لَمُحِيطَةٌۢ بِٱلْكَـٰفِرِينَ","en":"And among them is he who says, \"Permit me [to remain at home] and do not put me to trial.\" Unquestionably, into trial they have fallen.1 And indeed, Hell will encompass the disbelievers.","tr":"Waminhum man yaqoolu i/than lee walataftinnee ala fee alfitnati saqatoo wa-innajahannama lamuheetatun bilkafireen","juz":10,"page":195},{"s":9,"a":50,"key":"9:50","ar":"إِن تُصِبْكَ حَسَنَةٌ تَسُؤْهُمْ ۖ وَإِن تُصِبْكَ مُصِيبَةٌ يَقُولُوا۟ قَدْ أَخَذْنَآ أَمْرَنَا مِن قَبْلُ وَيَتَوَلَّوا۟ وَّهُمْ فَرِحُونَ","en":"If good befalls you, it distresses them; but if disaster strikes you, they say, \"We took our matter [in hand] before,\"1 and turn away while they are rejoicing.","tr":"In tusibka hasanatun tasu/humwa-in tusibka museebatun yaqooloo qad akhathnaamrana min qablu wayatawallaw wahum farihoon","juz":10,"page":195},{"s":9,"a":51,"key":"9:51","ar":"قُل لَّن يُصِيبَنَآ إِلَّا مَا كَتَبَ ٱللَّهُ لَنَا هُوَ مَوْلَىٰنَا ۚ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ","en":"Say, \"Never will we be struck except by what Allāh has decreed for us; He is our protector.\" And upon Allāh let the believers rely.","tr":"Qul lan yuseebana illama kataba Allahu lana huwa mawlanawaAAala Allahi falyatawakkali almu/minoon","juz":10,"page":195},{"s":9,"a":52,"key":"9:52","ar":"قُلْ هَلْ تَرَبَّصُونَ بِنَآ إِلَّآ إِحْدَى ٱلْحُسْنَيَيْنِ ۖ وَنَحْنُ نَتَرَبَّصُ بِكُمْ أَن يُصِيبَكُمُ ٱللَّهُ بِعَذَابٍ مِّنْ عِندِهِۦٓ أَوْ بِأَيْدِينَا ۖ فَتَرَبَّصُوٓا۟ إِنَّا مَعَكُم مُّتَرَبِّصُونَ","en":"Say, \"Do you await for us except one of the two best things [i.e., martyrdom or victory] while we await for you that Allāh will afflict you with punishment from Himself or at our hands? So wait; indeed we, along with you, are waiting.\"","tr":"Qul hal tarabbasoona bina illaihda alhusnayayni wanahnu natarabbasubikum an yuseebakumu Allahu biAAathabin minAAindihi aw bi-aydeena fatarabbasoo innamaAAakum mutarabbisoon","juz":10,"page":195},{"s":9,"a":53,"key":"9:53","ar":"قُلْ أَنفِقُوا۟ طَوْعًا أَوْ كَرْهًا لَّن يُتَقَبَّلَ مِنكُمْ ۖ إِنَّكُمْ كُنتُمْ قَوْمًا فَـٰسِقِينَ","en":"Say, \"Spend willingly or unwillingly; never will it be accepted from you. Indeed, you have been a defiantly disobedient people.\"","tr":"Qul anfiqoo tawAAan aw karhan lanyutaqabbala minkum innakum kuntum qawman fasiqeen","juz":10,"page":195},{"s":9,"a":54,"key":"9:54","ar":"وَمَا مَنَعَهُمْ أَن تُقْبَلَ مِنْهُمْ نَفَقَـٰتُهُمْ إِلَّآ أَنَّهُمْ كَفَرُوا۟ بِٱللَّهِ وَبِرَسُولِهِۦ وَلَا يَأْتُونَ ٱلصَّلَوٰةَ إِلَّا وَهُمْ كُسَالَىٰ وَلَا يُنفِقُونَ إِلَّا وَهُمْ كَـٰرِهُونَ","en":"And what prevents their expenditures from being accepted from them but that they have disbelieved in Allāh and in His Messenger and that they come not to prayer except while they are lazy and that they do not spend except while they are unwilling.","tr":"Wama manaAAahum an tuqbala minhumnafaqatuhum illa annahum kafaroo billahiwabirasoolihi wala ya/toona assalatailla wahum kusala wala yunfiqoona illawahum karihoon","juz":10,"page":195},{"s":9,"a":55,"key":"9:55","ar":"فَلَا تُعْجِبْكَ أَمْوَٰلُهُمْ وَلَآ أَوْلَـٰدُهُمْ ۚ إِنَّمَا يُرِيدُ ٱللَّهُ لِيُعَذِّبَهُم بِهَا فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَتَزْهَقَ أَنفُسُهُمْ وَهُمْ كَـٰفِرُونَ","en":"So let not their wealth or their children impress you. Allāh only intends to punish them through them in worldly life and that their souls should depart [at death] while they are disbelievers.","tr":"Fala tuAAjibka amwaluhum walaawladuhum innama yureedu Allahu liyuAAaththibahumbiha fee alhayati addunyawatazhaqa anfusuhum wahum kafiroon","juz":10,"page":196},{"s":9,"a":56,"key":"9:56","ar":"وَيَحْلِفُونَ بِٱللَّهِ إِنَّهُمْ لَمِنكُمْ وَمَا هُم مِّنكُمْ وَلَـٰكِنَّهُمْ قَوْمٌ يَفْرَقُونَ","en":"And they swear by Allāh that they are from among you while they are not from among you; but they are a people who are afraid.","tr":"Wayahlifoona billahiinnahum laminkum wama hum minkum walakinnahumqawmun yafraqoon","juz":10,"page":196},{"s":9,"a":57,"key":"9:57","ar":"لَوْ يَجِدُونَ مَلْجَـًٔا أَوْ مَغَـٰرَٰتٍ أَوْ مُدَّخَلًا لَّوَلَّوْا۟ إِلَيْهِ وَهُمْ يَجْمَحُونَ","en":"If they could find a refuge or some caves or any place to enter [and hide], they would turn to it while they run heedlessly.","tr":"Law yajidoona maljaan aw magharatinaw muddakhalan lawallaw ilayhi wahum yajmahoon","juz":10,"page":196},{"s":9,"a":58,"key":"9:58","ar":"وَمِنْهُم مَّن يَلْمِزُكَ فِى ٱلصَّدَقَـٰتِ فَإِنْ أُعْطُوا۟ مِنْهَا رَضُوا۟ وَإِن لَّمْ يُعْطَوْا۟ مِنْهَآ إِذَا هُمْ يَسْخَطُونَ","en":"And among them are some who criticize you concerning the [distribution of] charities. If they are given from them, they approve; but if they are not given from them, at once they become angry.","tr":"Waminhum man yalmizuka fee assadaqatifa-in oAAtoo minha radoo wa-in lam yuAAtawminha itha hum yaskhatoon","juz":10,"page":196},{"s":9,"a":59,"key":"9:59","ar":"وَلَوْ أَنَّهُمْ رَضُوا۟ مَآ ءَاتَىٰهُمُ ٱللَّهُ وَرَسُولُهُۥ وَقَالُوا۟ حَسْبُنَا ٱللَّهُ سَيُؤْتِينَا ٱللَّهُ مِن فَضْلِهِۦ وَرَسُولُهُۥٓ إِنَّآ إِلَى ٱللَّهِ رَٰغِبُونَ","en":"If only they had been satisfied with what Allāh and His Messenger gave them and said, \"Sufficient for us is Allāh; Allāh will give us of His bounty, and [so will] His Messenger; indeed, we are desirous toward Allāh,\"1 [it would have been better for them].","tr":"Walaw annahum radoo ma atahumuAllahu warasooluhu waqaloo hasbunaAllahu sayu/teena Allahu min fadlihiwarasooluhu inna ila Allahi raghiboon","juz":10,"page":196},{"s":9,"a":60,"key":"9:60","ar":"۞ إِنَّمَا ٱلصَّدَقَـٰتُ لِلْفُقَرَآءِ وَٱلْمَسَـٰكِينِ وَٱلْعَـٰمِلِينَ عَلَيْهَا وَٱلْمُؤَلَّفَةِ قُلُوبُهُمْ وَفِى ٱلرِّقَابِ وَٱلْغَـٰرِمِينَ وَفِى سَبِيلِ ٱللَّهِ وَٱبْنِ ٱلسَّبِيلِ ۖ فَرِيضَةً مِّنَ ٱللَّهِ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"Zakāh expenditures are only for the poor and for the needy and for those employed for it1 and for bringing hearts together [for Islām] and for freeing captives [or slaves] and for those in debt and for the cause of Allāh and for the [stranded] traveler - an obligation [imposed] by Allāh. And Allāh is Knowing and Wise.","tr":"Innama assadaqatulilfuqara-i walmasakeeni walAAamileenaAAalayha walmu-allafati quloobuhum wafee arriqabiwalgharimeena wafee sabeeli Allahi wabniassabeeli fareedatan mina Allahi wallahuAAaleemun hakeemun","juz":10,"page":196},{"s":9,"a":61,"key":"9:61","ar":"وَمِنْهُمُ ٱلَّذِينَ يُؤْذُونَ ٱلنَّبِىَّ وَيَقُولُونَ هُوَ أُذُنٌ ۚ قُلْ أُذُنُ خَيْرٍ لَّكُمْ يُؤْمِنُ بِٱللَّهِ وَيُؤْمِنُ لِلْمُؤْمِنِينَ وَرَحْمَةٌ لِّلَّذِينَ ءَامَنُوا۟ مِنكُمْ ۚ وَٱلَّذِينَ يُؤْذُونَ رَسُولَ ٱللَّهِ لَهُمْ عَذَابٌ أَلِيمٌ","en":"And among them are those who abuse the Prophet and say, \"He is an ear.\"1 Say, \"[It is] an ear of goodness for you that believes in Allāh and believes the believers and [is] a mercy to those who believe among you.\" And those who abuse the Messenger of Allāh - for them is a painful punishment.","tr":"Waminhumu allatheena yu/thoonaannabiyya wayaqooloona huwa othunun qul othunukhayrin lakum yu/minu billahi wayu/minulilmu/mineena warahmatun lillatheena amanoominkum wallatheena yu/thoona rasoola Allahilahum AAathabun aleem","juz":10,"page":196},{"s":9,"a":62,"key":"9:62","ar":"يَحْلِفُونَ بِٱللَّهِ لَكُمْ لِيُرْضُوكُمْ وَٱللَّهُ وَرَسُولُهُۥٓ أَحَقُّ أَن يُرْضُوهُ إِن كَانُوا۟ مُؤْمِنِينَ","en":"They swear by Allāh to you [Muslims] to satisfy you. But Allāh and His Messenger are more worthy for them to satisfy,1 if they were to be believers.","tr":"Yahlifoona billahilakum liyurdookum wallahu warasooluhu ahaqquan yurdoohu in kanoo mu/mineen","juz":10,"page":197},{"s":9,"a":63,"key":"9:63","ar":"أَلَمْ يَعْلَمُوٓا۟ أَنَّهُۥ مَن يُحَادِدِ ٱللَّهَ وَرَسُولَهُۥ فَأَنَّ لَهُۥ نَارَ جَهَنَّمَ خَـٰلِدًا فِيهَا ۚ ذَٰلِكَ ٱلْخِزْىُ ٱلْعَظِيمُ","en":"Do they not know that whoever opposes Allāh and His Messenger - that for him is the fire of Hell, wherein he will abide eternally? That is the great disgrace.","tr":"Alam yaAAlamoo annahu man yuhadidiAllaha warasoolahu faanna lahu nara jahannama khalidanfeeha thalika alkhizyu alAAatheem","juz":10,"page":197},{"s":9,"a":64,"key":"9:64","ar":"يَحْذَرُ ٱلْمُنَـٰفِقُونَ أَن تُنَزَّلَ عَلَيْهِمْ سُورَةٌ تُنَبِّئُهُم بِمَا فِى قُلُوبِهِمْ ۚ قُلِ ٱسْتَهْزِءُوٓا۟ إِنَّ ٱللَّهَ مُخْرِجٌ مَّا تَحْذَرُونَ","en":"The hypocrites are apprehensive lest a sūrah be revealed about them, informing them of1 what is in their hearts. Say, \"Mock [as you wish]; indeed, Allāh will expose that which you fear.\"","tr":"Yahtharu almunafiqoona antunazzala AAalayhim sooratun tunabbi-ohum bima feequloobihim quli istahzi-oo inna Allaha mukhrijun matahtharoon","juz":10,"page":197},{"s":9,"a":65,"key":"9:65","ar":"وَلَئِن سَأَلْتَهُمْ لَيَقُولُنَّ إِنَّمَا كُنَّا نَخُوضُ وَنَلْعَبُ ۚ قُلْ أَبِٱللَّهِ وَءَايَـٰتِهِۦ وَرَسُولِهِۦ كُنتُمْ تَسْتَهْزِءُونَ","en":"And if you ask them, they will surely say, \"We were only conversing and playing.\" Say, \"Is it Allāh and His verses and His Messenger that you were mocking?\"","tr":"Wala-in saaltahum layaqoolunna innamakunna nakhoodu wanalAAabu qul abillahiwaayatihi warasoolihi kuntum tastahzi-oon","juz":10,"page":197},{"s":9,"a":66,"key":"9:66","ar":"لَا تَعْتَذِرُوا۟ قَدْ كَفَرْتُم بَعْدَ إِيمَـٰنِكُمْ ۚ إِن نَّعْفُ عَن طَآئِفَةٍ مِّنكُمْ نُعَذِّبْ طَآئِفَةًۢ بِأَنَّهُمْ كَانُوا۟ مُجْرِمِينَ","en":"Make no excuse; you have disbelieved [i.e., rejected faith] after your belief. If We pardon one faction of you - We will punish another faction because they were criminals.","tr":"La taAAtathiroo qad kafartumbaAAda eemanikum in naAAfu AAan ta-ifatin minkumnuAAaththib ta-ifatan bi-annahum kanoomujrimeen","juz":10,"page":197},{"s":9,"a":67,"key":"9:67","ar":"ٱلْمُنَـٰفِقُونَ وَٱلْمُنَـٰفِقَـٰتُ بَعْضُهُم مِّنۢ بَعْضٍ ۚ يَأْمُرُونَ بِٱلْمُنكَرِ وَيَنْهَوْنَ عَنِ ٱلْمَعْرُوفِ وَيَقْبِضُونَ أَيْدِيَهُمْ ۚ نَسُوا۟ ٱللَّهَ فَنَسِيَهُمْ ۗ إِنَّ ٱلْمُنَـٰفِقِينَ هُمُ ٱلْفَـٰسِقُونَ","en":"The hypocrite men and hypocrite women are of one another. They enjoin what is wrong and forbid what is right and close their hands.1 They have forgotten Allāh, so He has forgotten them [accordingly]. Indeed, the hypocrites - it is they who are the defiantly disobedient.","tr":"Almunafiqoona walmunafiqatubaAAduhum min baAAdin ya/muroona bilmunkariwayanhawna AAani almaAAroofi wayaqbidoona aydiyahum nasooAllaha fanasiyahum inna almunafiqeena humu alfasiqoon","juz":10,"page":197},{"s":9,"a":68,"key":"9:68","ar":"وَعَدَ ٱللَّهُ ٱلْمُنَـٰفِقِينَ وَٱلْمُنَـٰفِقَـٰتِ وَٱلْكُفَّارَ نَارَ جَهَنَّمَ خَـٰلِدِينَ فِيهَا ۚ هِىَ حَسْبُهُمْ ۚ وَلَعَنَهُمُ ٱللَّهُ ۖ وَلَهُمْ عَذَابٌ مُّقِيمٌ","en":"Allāh has promised the hypocrite men and hypocrite women and the disbelievers the fire of Hell, wherein they will abide eternally. It is sufficient for them. And Allāh has cursed them, and for them is an enduring punishment.","tr":"WaAAada Allahu almunafiqeenawalmunafiqati walkuffara narajahannama khalideena feeha hiya hasbuhumwalaAAanahumu Allahu walahum AAathabun muqeem","juz":10,"page":197},{"s":9,"a":69,"key":"9:69","ar":"كَٱلَّذِينَ مِن قَبْلِكُمْ كَانُوٓا۟ أَشَدَّ مِنكُمْ قُوَّةً وَأَكْثَرَ أَمْوَٰلًا وَأَوْلَـٰدًا فَٱسْتَمْتَعُوا۟ بِخَلَـٰقِهِمْ فَٱسْتَمْتَعْتُم بِخَلَـٰقِكُمْ كَمَا ٱسْتَمْتَعَ ٱلَّذِينَ مِن قَبْلِكُم بِخَلَـٰقِهِمْ وَخُضْتُمْ كَٱلَّذِى خَاضُوٓا۟ ۚ أُو۟لَـٰٓئِكَ حَبِطَتْ أَعْمَـٰلُهُمْ فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ ۖ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْخَـٰسِرُونَ","en":"[You disbelievers are] like those before you; they were stronger than you in power and more abundant in wealth and children. They enjoyed their portion [of worldly enjoyment], and you have enjoyed your portion as those before you enjoyed their portion, and you have engaged [in vanities] like that in which they engaged. [It is] those whose deeds have become worthless in this world and in the Hereafter, and it is they who are the losers.","tr":"Kallatheena min qablikum kanooashadda minkum quwwatan waakthara amwalan waawladanfastamtaAAoo bikhalaqihim fastamtaAAtumbikhalaqikum kama istamtaAAa allatheena minqablikum bikhalaqihim wakhudtum kallatheekhadoo ola-ika habitat aAAmaluhumfee addunya wal-akhirati waola-ikahumu alkhasiroon","juz":10,"page":198},{"s":9,"a":70,"key":"9:70","ar":"أَلَمْ يَأْتِهِمْ نَبَأُ ٱلَّذِينَ مِن قَبْلِهِمْ قَوْمِ نُوحٍ وَعَادٍ وَثَمُودَ وَقَوْمِ إِبْرَٰهِيمَ وَأَصْحَـٰبِ مَدْيَنَ وَٱلْمُؤْتَفِكَـٰتِ ۚ أَتَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَـٰتِ ۖ فَمَا كَانَ ٱللَّهُ لِيَظْلِمَهُمْ وَلَـٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ","en":"Has there not reached them the news of those before them - the people of Noah and [the tribes of] ʿAad and Thamūd and the people of Abraham and the companions [i.e., dwellers] of Madyan and the towns overturned?1 Their messengers came to them with clear proofs. And Allāh would never have wronged them, but they were wronging themselves.","tr":"Alam ya/tihim nabao allatheena minqablihim qawmi noohin waAAadin wathamooda waqawmiibraheema waas-habi madyana walmu/tafikatiatat-hum rusuluhum bilbayyinati fama kanaAllahu liyathlimahum walakin kanooanfusahum yathlimoon","juz":10,"page":198},{"s":9,"a":71,"key":"9:71","ar":"وَٱلْمُؤْمِنُونَ وَٱلْمُؤْمِنَـٰتُ بَعْضُهُمْ أَوْلِيَآءُ بَعْضٍ ۚ يَأْمُرُونَ بِٱلْمَعْرُوفِ وَيَنْهَوْنَ عَنِ ٱلْمُنكَرِ وَيُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَيُطِيعُونَ ٱللَّهَ وَرَسُولَهُۥٓ ۚ أُو۟لَـٰٓئِكَ سَيَرْحَمُهُمُ ٱللَّهُ ۗ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ","en":"The believing men and believing women are allies of one another. They enjoin what is right and forbid what is wrong and establish prayer and give zakāh and obey Allāh and His Messenger. Those - Allāh will have mercy upon them. Indeed, Allāh is Exalted in Might and Wise.","tr":"Walmu/minoona walmu/minatubaAAduhum awliyao baAAdin ya/muroona bilmaAAroofiwayanhawna AAani almunkari wayuqeemoona assalatawayu/toona azzakata wayuteeAAoona Allahawarasoolahu ola-ika sayarhamuhumu Allahuinna Allaha AAazeezun hakeem","juz":10,"page":198},{"s":9,"a":72,"key":"9:72","ar":"وَعَدَ ٱللَّهُ ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَـٰتِ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا وَمَسَـٰكِنَ طَيِّبَةً فِى جَنَّـٰتِ عَدْنٍ ۚ وَرِضْوَٰنٌ مِّنَ ٱللَّهِ أَكْبَرُ ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"Allāh has promised the believing men and believing women gardens beneath which rivers flow, wherein they abide eternally, and pleasant dwellings in gardens of perpetual residence; but approval from Allāh is greater. It is that which is the great attainment.","tr":"WaAAada Allahu almu/mineena walmu/minatijannatin tajree min tahtiha al-anharukhalideena feeha wamasakina tayyibatanfee jannati AAadnin waridwanun mina Allahiakbaru thalika huwa alfawzu alAAatheem","juz":10,"page":198},{"s":9,"a":73,"key":"9:73","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ جَـٰهِدِ ٱلْكُفَّارَ وَٱلْمُنَـٰفِقِينَ وَٱغْلُظْ عَلَيْهِمْ ۚ وَمَأْوَىٰهُمْ جَهَنَّمُ ۖ وَبِئْسَ ٱلْمَصِيرُ","en":"O Prophet, fight against the disbelievers and the hypocrites and be harsh upon them. And their refuge is Hell, and wretched is the destination.","tr":"Ya ayyuha annabiyyu jahidialkuffara walmunafiqeena waghluthAAalayhim wama/wahum jahannamu wabi/sa almaseer","juz":10,"page":199},{"s":9,"a":74,"key":"9:74","ar":"يَحْلِفُونَ بِٱللَّهِ مَا قَالُوا۟ وَلَقَدْ قَالُوا۟ كَلِمَةَ ٱلْكُفْرِ وَكَفَرُوا۟ بَعْدَ إِسْلَـٰمِهِمْ وَهَمُّوا۟ بِمَا لَمْ يَنَالُوا۟ ۚ وَمَا نَقَمُوٓا۟ إِلَّآ أَنْ أَغْنَىٰهُمُ ٱللَّهُ وَرَسُولُهُۥ مِن فَضْلِهِۦ ۚ فَإِن يَتُوبُوا۟ يَكُ خَيْرًا لَّهُمْ ۖ وَإِن يَتَوَلَّوْا۟ يُعَذِّبْهُمُ ٱللَّهُ عَذَابًا أَلِيمًا فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ ۚ وَمَا لَهُمْ فِى ٱلْأَرْضِ مِن وَلِىٍّ وَلَا نَصِيرٍ","en":"They swear by Allāh that they did not say [anything against the Prophet (ﷺ)] while they had said the word of disbelief and disbelieved after their [pretense of] Islām and planned that which they were not to attain.1 And they were not resentful except [for the fact] that Allāh and His Messenger had enriched them of His bounty.2 So if they repent, it is better for them; but if they turn away, Allāh will punish them with a painful punishment in this world and the Hereafter. And there will not be for them on earth any protector or helper.","tr":"Yahlifoona billahi maqaloo walaqad qaloo kalimata alkufri wakafaroobaAAda islamihim wahammoo bima lam yanaloowama naqamoo illa an aghnahumu Allahuwarasooluhu min fadlihi fa-in yatooboo yaku khayran lahumwa-in yatawallaw yuAAaththibhumu Allahu AAathabanaleeman fee addunya wal-akhiratiwama lahum fee al-ardi min waliyyin wala naseer","juz":10,"page":199},{"s":9,"a":75,"key":"9:75","ar":"۞ وَمِنْهُم مَّنْ عَـٰهَدَ ٱللَّهَ لَئِنْ ءَاتَىٰنَا مِن فَضْلِهِۦ لَنَصَّدَّقَنَّ وَلَنَكُونَنَّ مِنَ ٱلصَّـٰلِحِينَ","en":"And among them are those who made a covenant with Allāh, [saying], \"If He should give us from His bounty, we will surely spend in charity, and we will surely be among the righteous.\"","tr":"Waminhum man AAahada Allahala-in atana min fadlihi lanassaddaqannawalanakoonanna mina assaliheen","juz":10,"page":199},{"s":9,"a":76,"key":"9:76","ar":"فَلَمَّآ ءَاتَىٰهُم مِّن فَضْلِهِۦ بَخِلُوا۟ بِهِۦ وَتَوَلَّوا۟ وَّهُم مُّعْرِضُونَ","en":"But when He gave them from His bounty, they were stingy with it and turned away while they refused.","tr":"Falamma atahum min fadlihibakhiloo bihi watawallaw wahum muAAridoon","juz":10,"page":199},{"s":9,"a":77,"key":"9:77","ar":"فَأَعْقَبَهُمْ نِفَاقًا فِى قُلُوبِهِمْ إِلَىٰ يَوْمِ يَلْقَوْنَهُۥ بِمَآ أَخْلَفُوا۟ ٱللَّهَ مَا وَعَدُوهُ وَبِمَا كَانُوا۟ يَكْذِبُونَ","en":"So He penalized them with hypocrisy in their hearts until the Day they will meet Him - because they failed Allāh in what they promised Him and because they [habitually] used to lie.","tr":"FaaAAqabahum nifaqan fee quloobihimila yawmi yalqawnahu bima akhlafoo Allaha mawaAAadoohu wabima kanoo yakthiboon","juz":10,"page":199},{"s":9,"a":78,"key":"9:78","ar":"أَلَمْ يَعْلَمُوٓا۟ أَنَّ ٱللَّهَ يَعْلَمُ سِرَّهُمْ وَنَجْوَىٰهُمْ وَأَنَّ ٱللَّهَ عَلَّـٰمُ ٱلْغُيُوبِ","en":"Did they not know that Allāh knows their secrets and their private conversations and that Allāh is the Knower of the unseen?","tr":"Alam yaAAlamoo anna Allaha yaAAlamusirrahum wanajwahum waanna Allaha AAallamualghuyoob","juz":10,"page":199},{"s":9,"a":79,"key":"9:79","ar":"ٱلَّذِينَ يَلْمِزُونَ ٱلْمُطَّوِّعِينَ مِنَ ٱلْمُؤْمِنِينَ فِى ٱلصَّدَقَـٰتِ وَٱلَّذِينَ لَا يَجِدُونَ إِلَّا جُهْدَهُمْ فَيَسْخَرُونَ مِنْهُمْ ۙ سَخِرَ ٱللَّهُ مِنْهُمْ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"Those who criticize the contributors among the believers concerning [their] charities and [criticize] the ones who find nothing [to spend] except their effort, so they ridicule them - Allāh will ridicule them, and they will have a painful punishment.","tr":"Allatheena yalmizoona almuttawwiAAeenamina almu/mineena fee assadaqati wallatheenala yajidoona illa juhdahum fayaskharoona minhumsakhira Allahu minhum walahum AAathabun aleem","juz":10,"page":199},{"s":9,"a":80,"key":"9:80","ar":"ٱسْتَغْفِرْ لَهُمْ أَوْ لَا تَسْتَغْفِرْ لَهُمْ إِن تَسْتَغْفِرْ لَهُمْ سَبْعِينَ مَرَّةً فَلَن يَغْفِرَ ٱللَّهُ لَهُمْ ۚ ذَٰلِكَ بِأَنَّهُمْ كَفَرُوا۟ بِٱللَّهِ وَرَسُولِهِۦ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلْفَـٰسِقِينَ","en":"Ask forgiveness for them, [O Muḥammad], or do not ask forgiveness for them. If you should ask forgiveness for them seventy times - never will Allāh forgive them. That is because they disbelieved in Allāh and His Messenger, and Allāh does not guide the defiantly disobedient people.","tr":"Istaghfir lahum aw la tastaghfirlahum in tastaghfir lahum sabAAeena marratan falan yaghfira Allahulahum thalika bi-annahum kafaroo billahiwarasoolihi wallahu la yahdee alqawma alfasiqeen","juz":10,"page":200},{"s":9,"a":81,"key":"9:81","ar":"فَرِحَ ٱلْمُخَلَّفُونَ بِمَقْعَدِهِمْ خِلَـٰفَ رَسُولِ ٱللَّهِ وَكَرِهُوٓا۟ أَن يُجَـٰهِدُوا۟ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ فِى سَبِيلِ ٱللَّهِ وَقَالُوا۟ لَا تَنفِرُوا۟ فِى ٱلْحَرِّ ۗ قُلْ نَارُ جَهَنَّمَ أَشَدُّ حَرًّا ۚ لَّوْ كَانُوا۟ يَفْقَهُونَ","en":"Those who remained behind1 rejoiced in their staying [at home] after [the departure of] the Messenger of Allāh and disliked to strive with their wealth and their lives in the cause of Allāh and said, \"Do not go forth in the heat.\" Say, \"The fire of Hell is more intense in heat\" - if they would but understand.","tr":"Fariha almukhallafoona bimaqAAadihimkhilafa rasooli Allahi wakarihoo an yujahidoobi-amwalihim waanfusihim fee sabeeli Allahi waqaloola tanfiroo fee alharri qul naru jahannamaashaddu harran law kanoo yafqahoon","juz":10,"page":200},{"s":9,"a":82,"key":"9:82","ar":"فَلْيَضْحَكُوا۟ قَلِيلًا وَلْيَبْكُوا۟ كَثِيرًا جَزَآءًۢ بِمَا كَانُوا۟ يَكْسِبُونَ","en":"So let them laugh a little and [then] weep much as recompense for what they used to earn.","tr":"Falyadhakoo qaleelan walyabkookatheeran jazaan bima kanoo yaksiboon","juz":10,"page":200},{"s":9,"a":83,"key":"9:83","ar":"فَإِن رَّجَعَكَ ٱللَّهُ إِلَىٰ طَآئِفَةٍ مِّنْهُمْ فَٱسْتَـْٔذَنُوكَ لِلْخُرُوجِ فَقُل لَّن تَخْرُجُوا۟ مَعِىَ أَبَدًا وَلَن تُقَـٰتِلُوا۟ مَعِىَ عَدُوًّا ۖ إِنَّكُمْ رَضِيتُم بِٱلْقُعُودِ أَوَّلَ مَرَّةٍ فَٱقْعُدُوا۟ مَعَ ٱلْخَـٰلِفِينَ","en":"If Allāh should return you to a faction of them [after the expedition] and then they ask your permission to go out [to battle], say, \"You will not go out with me, ever, and you will never fight with me an enemy. Indeed, you were satisfied with sitting [at home] the first time, so sit [now] with those who stay behind.\"","tr":"Fa-in rajaAAaka Allahu ila ta-ifatinminhum fasta/thanooka lilkhurooji faqul lantakhrujoo maAAiya abadan walan tuqatiloo maAAiya AAaduwwaninnakum radeetum bilquAAoodi awwala marratin faqAAudoomaAAa alkhalifeen","juz":10,"page":200},{"s":9,"a":84,"key":"9:84","ar":"وَلَا تُصَلِّ عَلَىٰٓ أَحَدٍ مِّنْهُم مَّاتَ أَبَدًا وَلَا تَقُمْ عَلَىٰ قَبْرِهِۦٓ ۖ إِنَّهُمْ كَفَرُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَمَاتُوا۟ وَهُمْ فَـٰسِقُونَ","en":"And do not pray [the funeral prayer, O Muḥammad], over any of them who has died - ever - or stand at his grave. Indeed, they disbelieved in Allāh and His Messenger and died while they were defiantly disobedient.","tr":"Wala tusalli AAala ahadinminhum mata abadan wala taqum AAala qabrihiinnahum kafaroo billahi warasoolihi wamatoowahum fasiqoon","juz":10,"page":200},{"s":9,"a":85,"key":"9:85","ar":"وَلَا تُعْجِبْكَ أَمْوَٰلُهُمْ وَأَوْلَـٰدُهُمْ ۚ إِنَّمَا يُرِيدُ ٱللَّهُ أَن يُعَذِّبَهُم بِهَا فِى ٱلدُّنْيَا وَتَزْهَقَ أَنفُسُهُمْ وَهُمْ كَـٰفِرُونَ","en":"And let not their wealth and their children impress you. Allāh only intends to punish them through them in this world and that their souls should depart [at death] while they are disbelievers.","tr":"Wala tuAAjibka amwaluhum waawladuhuminnama yureedu Allahu an yuAAaththibahum bihafee addunya watazhaqa anfusuhum wahum kafiroon","juz":10,"page":200},{"s":9,"a":86,"key":"9:86","ar":"وَإِذَآ أُنزِلَتْ سُورَةٌ أَنْ ءَامِنُوا۟ بِٱللَّهِ وَجَـٰهِدُوا۟ مَعَ رَسُولِهِ ٱسْتَـْٔذَنَكَ أُو۟لُوا۟ ٱلطَّوْلِ مِنْهُمْ وَقَالُوا۟ ذَرْنَا نَكُن مَّعَ ٱلْقَـٰعِدِينَ","en":"And when a sūrah was revealed [enjoining them] to believe in Allāh and to fight with His Messenger, those of wealth among them asked your permission [to stay back] and said, \"Leave us to be with them who sit [at home].\"","tr":"Wa-itha onzilat sooratun an aminoobillahi wajahidoo maAAa rasoolihi ista/thanakaoloo attawli minhum waqaloo tharnanakun maAAa alqaAAideen","juz":10,"page":200},{"s":9,"a":87,"key":"9:87","ar":"رَضُوا۟ بِأَن يَكُونُوا۟ مَعَ ٱلْخَوَالِفِ وَطُبِعَ عَلَىٰ قُلُوبِهِمْ فَهُمْ لَا يَفْقَهُونَ","en":"They were satisfied to be with those who stay behind, and their hearts were sealed over, so they do not understand.","tr":"Radoo bi-an yakoonoo maAAa alkhawalifiwatubiAAa AAala quloobihim fahum layafqahoon","juz":10,"page":201},{"s":9,"a":88,"key":"9:88","ar":"لَـٰكِنِ ٱلرَّسُولُ وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ جَـٰهَدُوا۟ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ ۚ وَأُو۟لَـٰٓئِكَ لَهُمُ ٱلْخَيْرَٰتُ ۖ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"But the Messenger and those who believed with him fought with their wealth and their lives. Those will have [all that is] good and it is those who are the successful.","tr":"Lakini arrasoolu wallatheenaamanoo maAAahu jahadoo bi-amwalihimwaanfusihim waola-ika lahumu alkhayratu waola-ikahumu almuflihoon","juz":10,"page":201},{"s":9,"a":89,"key":"9:89","ar":"أَعَدَّ ٱللَّهُ لَهُمْ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا ۚ ذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"Allāh has prepared for them gardens beneath which rivers flow, wherein they will abide eternally. That is the great attainment.","tr":"aAAadda Allahu lahum jannatintajree min tahtiha al-anharu khalideenafeeha thalika alfawzu alAAatheem","juz":10,"page":201},{"s":9,"a":90,"key":"9:90","ar":"وَجَآءَ ٱلْمُعَذِّرُونَ مِنَ ٱلْأَعْرَابِ لِيُؤْذَنَ لَهُمْ وَقَعَدَ ٱلَّذِينَ كَذَبُوا۟ ٱللَّهَ وَرَسُولَهُۥ ۚ سَيُصِيبُ ٱلَّذِينَ كَفَرُوا۟ مِنْهُمْ عَذَابٌ أَلِيمٌ","en":"And those with excuses among the bedouins came to be permitted [to remain], and they who had lied1 to Allāh and His Messenger sat [at home]. There will strike those who disbelieved among them a painful punishment.","tr":"Wajaa almuAAaththiroona minaal-aAArabi liyu/thana lahum waqaAAada allatheenakathaboo Allaha warasoolahu sayuseebu allatheenakafaroo minhum AAathabun aleem","juz":10,"page":201},{"s":9,"a":91,"key":"9:91","ar":"لَّيْسَ عَلَى ٱلضُّعَفَآءِ وَلَا عَلَى ٱلْمَرْضَىٰ وَلَا عَلَى ٱلَّذِينَ لَا يَجِدُونَ مَا يُنفِقُونَ حَرَجٌ إِذَا نَصَحُوا۟ لِلَّهِ وَرَسُولِهِۦ ۚ مَا عَلَى ٱلْمُحْسِنِينَ مِن سَبِيلٍ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"There is not upon the weak or upon the ill or upon those who do not find anything to spend any discomfort [i.e., guilt] when they are sincere to Allāh and His Messenger. There is not upon the doers of good any cause [for blame]. And Allāh is Forgiving and Merciful.","tr":"Laysa AAala adduAAafa-iwala AAala almarda wala AAalaallatheena la yajidoona ma yunfiqoona harajunitha nasahoo lillahi warasoolihi maAAala almuhsineena min sabeelin wallahughafoorun raheem","juz":10,"page":201},{"s":9,"a":92,"key":"9:92","ar":"وَلَا عَلَى ٱلَّذِينَ إِذَا مَآ أَتَوْكَ لِتَحْمِلَهُمْ قُلْتَ لَآ أَجِدُ مَآ أَحْمِلُكُمْ عَلَيْهِ تَوَلَّوا۟ وَّأَعْيُنُهُمْ تَفِيضُ مِنَ ٱلدَّمْعِ حَزَنًا أَلَّا يَجِدُوا۟ مَا يُنفِقُونَ","en":"Nor [is there blame] upon those who, when they came to you for you to take them along, you said, \"I can find nothing upon which to carry you.\"1 They turned back while their eyes overflowed with tears out of grief that they could not find something to spend [for the cause of Allāh].","tr":"Wala AAala allatheena ithama atawka litahmilahum qulta la ajidu maahmilukum AAalayhi tawallaw waaAAyunuhum tafeedumina addamAAi hazanan alla yajidoo mayunfiqoon","juz":10,"page":201},{"s":9,"a":93,"key":"9:93","ar":"۞ إِنَّمَا ٱلسَّبِيلُ عَلَى ٱلَّذِينَ يَسْتَـْٔذِنُونَكَ وَهُمْ أَغْنِيَآءُ ۚ رَضُوا۟ بِأَن يَكُونُوا۟ مَعَ ٱلْخَوَالِفِ وَطَبَعَ ٱللَّهُ عَلَىٰ قُلُوبِهِمْ فَهُمْ لَا يَعْلَمُونَ","en":"The cause [for blame] is only upon those who ask permission of you while they are rich. They are satisfied to be with those who stay behind, and Allāh has sealed over their hearts, so they do not know.","tr":"Innama assabeelu AAalaallatheena yasta/thinoonaka wahum aghniyaoradoo bi-an yakoonoo maAAa alkhawalifi watabaAAaAllahu AAala quloobihim fahum la yaAAlamoon","juz":11,"page":201},{"s":9,"a":94,"key":"9:94","ar":"يَعْتَذِرُونَ إِلَيْكُمْ إِذَا رَجَعْتُمْ إِلَيْهِمْ ۚ قُل لَّا تَعْتَذِرُوا۟ لَن نُّؤْمِنَ لَكُمْ قَدْ نَبَّأَنَا ٱللَّهُ مِنْ أَخْبَارِكُمْ ۚ وَسَيَرَى ٱللَّهُ عَمَلَكُمْ وَرَسُولُهُۥ ثُمَّ تُرَدُّونَ إِلَىٰ عَـٰلِمِ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ فَيُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ","en":"They will make excuses to you when you have returned to them. Say, \"Make no excuse - never will we believe you. Allāh has already informed us of your news [i.e., affair]. And Allāh will observe your deeds, and [so will] His Messenger; then you will be taken back to the Knower of the unseen and the witnessed,1 and He will inform you of what you used to do.\"","tr":"YaAAtathiroona ilaykum itharajaAAtum ilayhim qul la taAAtathiroo lan nu/minalakum qad nabbaana Allahu min akhbarikumwasayara Allahu AAamalakum warasooluhu thummaturaddoona ila AAalimi alghaybi washshahadatifayunabbi-okum bima kuntum taAAmaloon","juz":11,"page":202},{"s":9,"a":95,"key":"9:95","ar":"سَيَحْلِفُونَ بِٱللَّهِ لَكُمْ إِذَا ٱنقَلَبْتُمْ إِلَيْهِمْ لِتُعْرِضُوا۟ عَنْهُمْ ۖ فَأَعْرِضُوا۟ عَنْهُمْ ۖ إِنَّهُمْ رِجْسٌ ۖ وَمَأْوَىٰهُمْ جَهَنَّمُ جَزَآءًۢ بِمَا كَانُوا۟ يَكْسِبُونَ","en":"They will swear by Allāh to you when you return to them that you would leave them alone. So leave them alone; indeed they are evil; and their refuge is Hell as recompense for what they had been earning.","tr":"Sayahlifoona billahilakum itha inqalabtum ilayhim lituAAridoo AAanhumfaaAAridoo AAanhum innahum rijsun wama/wahumjahannamu jazaan bima kanoo yaksiboon","juz":11,"page":202},{"s":9,"a":96,"key":"9:96","ar":"يَحْلِفُونَ لَكُمْ لِتَرْضَوْا۟ عَنْهُمْ ۖ فَإِن تَرْضَوْا۟ عَنْهُمْ فَإِنَّ ٱللَّهَ لَا يَرْضَىٰ عَنِ ٱلْقَوْمِ ٱلْفَـٰسِقِينَ","en":"They swear to you so that you might be satisfied with them. But if you should be satisfied with them - indeed, Allāh is not satisfied with a defiantly disobedient people.","tr":"Yahlifoona lakum litardawAAanhum fa-in tardaw AAanhum fa-inna Allaha layarda AAani alqawmi alfasiqeen","juz":11,"page":202},{"s":9,"a":97,"key":"9:97","ar":"ٱلْأَعْرَابُ أَشَدُّ كُفْرًا وَنِفَاقًا وَأَجْدَرُ أَلَّا يَعْلَمُوا۟ حُدُودَ مَآ أَنزَلَ ٱللَّهُ عَلَىٰ رَسُولِهِۦ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"The bedouins are stronger in disbelief and hypocrisy and more likely not to know the limits of what [laws] Allāh has revealed to His Messenger. And Allāh is Knowing and Wise.","tr":"Al-aAArabu ashaddu kufran wanifaqanwaajdaru alla yaAAlamoo hudooda ma anzalaAllahu AAala rasoolihi wallahuAAaleemun hakeem","juz":11,"page":202},{"s":9,"a":98,"key":"9:98","ar":"وَمِنَ ٱلْأَعْرَابِ مَن يَتَّخِذُ مَا يُنفِقُ مَغْرَمًا وَيَتَرَبَّصُ بِكُمُ ٱلدَّوَآئِرَ ۚ عَلَيْهِمْ دَآئِرَةُ ٱلسَّوْءِ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ","en":"And among the bedouins are some who consider what they spend as a loss1 and await for you turns of misfortune. Upon them will be a misfortune of evil. And Allāh is Hearing and Knowing.","tr":"Wamina al-aAArabi man yattakhithuma yunfiqu maghraman wayatarabbasu bikumu addawa-iraAAalayhim da-iratu assaw-i wallahusameeAAun AAaleem","juz":11,"page":202},{"s":9,"a":99,"key":"9:99","ar":"وَمِنَ ٱلْأَعْرَابِ مَن يُؤْمِنُ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ وَيَتَّخِذُ مَا يُنفِقُ قُرُبَـٰتٍ عِندَ ٱللَّهِ وَصَلَوَٰتِ ٱلرَّسُولِ ۚ أَلَآ إِنَّهَا قُرْبَةٌ لَّهُمْ ۚ سَيُدْخِلُهُمُ ٱللَّهُ فِى رَحْمَتِهِۦٓ ۗ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"But among the bedouins are some who believe in Allāh and the Last Day and consider what they spend as means of nearness to Allāh and of [obtaining] invocations of the Messenger. Unquestionably, it is a means of nearness for them. Allāh will admit them to His mercy. Indeed, Allāh is Forgiving and Merciful.","tr":"Wamina al-aAArabi man yu/minu billahiwalyawmi al-akhiri wayattakhithu mayunfiqu qurubatin AAinda Allahi wasalawatiarrasooli ala innaha qurbatun lahumsayudkhiluhumu Allahu fee rahmatihi inna Allahaghafoorun raheem","juz":11,"page":202},{"s":9,"a":100,"key":"9:100","ar":"وَٱلسَّـٰبِقُونَ ٱلْأَوَّلُونَ مِنَ ٱلْمُهَـٰجِرِينَ وَٱلْأَنصَارِ وَٱلَّذِينَ ٱتَّبَعُوهُم بِإِحْسَـٰنٍ رَّضِىَ ٱللَّهُ عَنْهُمْ وَرَضُوا۟ عَنْهُ وَأَعَدَّ لَهُمْ جَنَّـٰتٍ تَجْرِى تَحْتَهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَدًا ۚ ذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"And the first forerunners [in the faith] among the Muhājireen1 and the Anṣār2 and those who followed them with good conduct - Allāh is pleased with them and they are pleased with Him, and He has prepared for them gardens beneath which rivers flow, wherein they will abide forever. That is the great attainment.","tr":"Wassabiqoona al-awwaloonamina almuhajireena wal-ansari wallatheenaittabaAAoohum bi-ihsanin radiya AllahuAAanhum waradoo AAanhu waaAAadda lahum jannatintajree tahtaha al-anharu khalideenafeeha abadan thalika alfawzu alAAatheem","juz":11,"page":203},{"s":9,"a":101,"key":"9:101","ar":"وَمِمَّنْ حَوْلَكُم مِّنَ ٱلْأَعْرَابِ مُنَـٰفِقُونَ ۖ وَمِنْ أَهْلِ ٱلْمَدِينَةِ ۖ مَرَدُوا۟ عَلَى ٱلنِّفَاقِ لَا تَعْلَمُهُمْ ۖ نَحْنُ نَعْلَمُهُمْ ۚ سَنُعَذِّبُهُم مَّرَّتَيْنِ ثُمَّ يُرَدُّونَ إِلَىٰ عَذَابٍ عَظِيمٍ","en":"And among those around you of the bedouins are hypocrites, and [also] from the people of Madīnah. They have persisted in hypocrisy. You, [O Muḥammad], do not know them, [but] We know them. We will punish them twice [in this world]; then they will be returned to a great punishment.","tr":"Wamimman hawlakum mina al-aAArabimunafiqoona wamin ahli almadeenati maradoo AAala annifaqila taAAlamuhum nahnu naAAlamuhum sanuAAaththibuhummarratayni thumma yuraddoona ila AAathabin AAatheem","juz":11,"page":203},{"s":9,"a":102,"key":"9:102","ar":"وَءَاخَرُونَ ٱعْتَرَفُوا۟ بِذُنُوبِهِمْ خَلَطُوا۟ عَمَلًا صَـٰلِحًا وَءَاخَرَ سَيِّئًا عَسَى ٱللَّهُ أَن يَتُوبَ عَلَيْهِمْ ۚ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"And [there are] others who have acknowledged their sins. They had mixed [i.e., polluted] a righteous deed with another that was bad.1 Perhaps Allāh will turn to them in forgiveness. Indeed, Allāh is Forgiving and Merciful.","tr":"Waakharoona iAAtarafoo bithunoobihimkhalatoo AAamalan salihan waakharasayyi-an AAasa Allahu an yatooba AAalayhim inna Allahaghafoorun raheem","juz":11,"page":203},{"s":9,"a":103,"key":"9:103","ar":"خُذْ مِنْ أَمْوَٰلِهِمْ صَدَقَةً تُطَهِّرُهُمْ وَتُزَكِّيهِم بِهَا وَصَلِّ عَلَيْهِمْ ۖ إِنَّ صَلَوٰتَكَ سَكَنٌ لَّهُمْ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ","en":"Take, [O Muḥammad], from their wealth a charity by which you purify them and cause them increase, and invoke [Allāh's blessings] upon them. Indeed, your invocations are reassurance for them. And Allāh is Hearing and Knowing.","tr":"Khuth min amwalihim sadaqatantutahhiruhum watuzakkeehim biha wasalliAAalayhim inna salataka sakanun lahum wallahusameeAAun AAaleem","juz":11,"page":203},{"s":9,"a":104,"key":"9:104","ar":"أَلَمْ يَعْلَمُوٓا۟ أَنَّ ٱللَّهَ هُوَ يَقْبَلُ ٱلتَّوْبَةَ عَنْ عِبَادِهِۦ وَيَأْخُذُ ٱلصَّدَقَـٰتِ وَأَنَّ ٱللَّهَ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ","en":"Do they not know that it is Allāh who accepts repentance from His servants and receives charities and that it is Allāh who is the Accepting of Repentance,1 the Merciful?","tr":"Alam yaAAlamoo anna Allaha huwayaqbalu attawbata AAan AAibadihi waya/khuthuassadaqati waanna Allaha huwa attawwabuarraheem","juz":11,"page":203},{"s":9,"a":105,"key":"9:105","ar":"وَقُلِ ٱعْمَلُوا۟ فَسَيَرَى ٱللَّهُ عَمَلَكُمْ وَرَسُولُهُۥ وَٱلْمُؤْمِنُونَ ۖ وَسَتُرَدُّونَ إِلَىٰ عَـٰلِمِ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ فَيُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ","en":"And say, \"Do [as you will], for Allāh will see your deeds, and [so will] His Messenger and the believers. And you will be returned to the Knower of the unseen and the witnessed, and He will inform you of what you used to do.\"","tr":"Waquli iAAmaloo fasayara AllahuAAamalakum warasooluhu walmu/minoona wasaturaddoona ilaAAalimi alghaybi washshahadatifayunabbi-okum bima kuntum taAAmaloon","juz":11,"page":203},{"s":9,"a":106,"key":"9:106","ar":"وَءَاخَرُونَ مُرْجَوْنَ لِأَمْرِ ٱللَّهِ إِمَّا يُعَذِّبُهُمْ وَإِمَّا يَتُوبُ عَلَيْهِمْ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"And [there are] others deferred until the command of Allāh - whether He will punish them or whether He will forgive them. And Allāh is Knowing and Wise.","tr":"Waakharoona murjawna li-amri Allahiimma yuAAaththibuhum wa-imma yatoobuAAalayhim wallahu AAaleemun hakeem","juz":11,"page":203},{"s":9,"a":107,"key":"9:107","ar":"وَٱلَّذِينَ ٱتَّخَذُوا۟ مَسْجِدًا ضِرَارًا وَكُفْرًا وَتَفْرِيقًۢا بَيْنَ ٱلْمُؤْمِنِينَ وَإِرْصَادًا لِّمَنْ حَارَبَ ٱللَّهَ وَرَسُولَهُۥ مِن قَبْلُ ۚ وَلَيَحْلِفُنَّ إِنْ أَرَدْنَآ إِلَّا ٱلْحُسْنَىٰ ۖ وَٱللَّهُ يَشْهَدُ إِنَّهُمْ لَكَـٰذِبُونَ","en":"And [there are] those [hypocrites] who took for themselves a mosque for causing harm and disbelief and division among the believers and as a station for whoever had warred against Allāh and His Messenger before. And they will surely swear, \"We intended only the best.\" And Allāh testifies that indeed they are liars.","tr":"Wallatheena ittakhathoomasjidan diraran wakufran watafreeqan baynaalmu/mineena wa-irsadan liman haraba Allahawarasoolahu min qablu walayahlifunna in aradna illaalhusna wallahu yashhadu innahum lakathiboon","juz":11,"page":204},{"s":9,"a":108,"key":"9:108","ar":"لَا تَقُمْ فِيهِ أَبَدًا ۚ لَّمَسْجِدٌ أُسِّسَ عَلَى ٱلتَّقْوَىٰ مِنْ أَوَّلِ يَوْمٍ أَحَقُّ أَن تَقُومَ فِيهِ ۚ فِيهِ رِجَالٌ يُحِبُّونَ أَن يَتَطَهَّرُوا۟ ۚ وَٱللَّهُ يُحِبُّ ٱلْمُطَّهِّرِينَ","en":"Do not stand [for prayer] within it - ever. A mosque founded on righteousness from the first day1 is more worthy for you to stand in. Within it are men who love to purify themselves; and Allāh loves those who purify themselves.","tr":"La taqum feehi abadan lamasjidunossisa AAala attaqwa min awwali yawmin ahaqquan taqooma feehi feehi rijalun yuhibboona an yatatahharoowallahu yuhibbu almuttahhireen","juz":11,"page":204},{"s":9,"a":109,"key":"9:109","ar":"أَفَمَنْ أَسَّسَ بُنْيَـٰنَهُۥ عَلَىٰ تَقْوَىٰ مِنَ ٱللَّهِ وَرِضْوَٰنٍ خَيْرٌ أَم مَّنْ أَسَّسَ بُنْيَـٰنَهُۥ عَلَىٰ شَفَا جُرُفٍ هَارٍ فَٱنْهَارَ بِهِۦ فِى نَارِ جَهَنَّمَ ۗ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"Then is one who laid the foundation of his building on righteousness [with fear] from Allāh and [seeking] His approval better or one who laid the foundation of his building on the edge of a bank about to collapse, so it collapsed with him into the fire of Hell? And Allāh does not guide the wrongdoing people.","tr":"Afaman assasa bunyanahu AAalataqwa mina Allahi waridwanin khayrunam man assasa bunyanahu AAala shafa jurufinharin fanhara bihi fee narijahannama wallahu la yahdee alqawma aththalimeen","juz":11,"page":204},{"s":9,"a":110,"key":"9:110","ar":"لَا يَزَالُ بُنْيَـٰنُهُمُ ٱلَّذِى بَنَوْا۟ رِيبَةً فِى قُلُوبِهِمْ إِلَّآ أَن تَقَطَّعَ قُلُوبُهُمْ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"Their building which they built will not cease to be a [cause of] skepticism in their hearts until their hearts are cut [i.e., stopped]. And Allāh is Knowing and Wise.","tr":"La yazalu bunyanuhumuallathee banaw reebatan fee quloobihim illa an taqattaAAaquloobuhum wallahu AAaleemun hakeem","juz":11,"page":204},{"s":9,"a":111,"key":"9:111","ar":"۞ إِنَّ ٱللَّهَ ٱشْتَرَىٰ مِنَ ٱلْمُؤْمِنِينَ أَنفُسَهُمْ وَأَمْوَٰلَهُم بِأَنَّ لَهُمُ ٱلْجَنَّةَ ۚ يُقَـٰتِلُونَ فِى سَبِيلِ ٱللَّهِ فَيَقْتُلُونَ وَيُقْتَلُونَ ۖ وَعْدًا عَلَيْهِ حَقًّا فِى ٱلتَّوْرَىٰةِ وَٱلْإِنجِيلِ وَٱلْقُرْءَانِ ۚ وَمَنْ أَوْفَىٰ بِعَهْدِهِۦ مِنَ ٱللَّهِ ۚ فَٱسْتَبْشِرُوا۟ بِبَيْعِكُمُ ٱلَّذِى بَايَعْتُم بِهِۦ ۚ وَذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"Indeed, Allāh has purchased from the believers their lives and their properties [in exchange] for that they will have Paradise. They fight in the cause of Allāh, so they kill and are killed. [It is] a true promise [binding] upon Him in the Torah and the Gospel and the Qur’ān. And who is truer to his covenant than Allāh? So rejoice in your transaction which you have contracted. And it is that which is the great attainment.","tr":"Inna Allaha ishtara minaalmu/mineena anfusahum waamwalahum bi-anna lahumualjannata yuqatiloona fee sabeeli Allahifayaqtuloona wayuqtaloona waAAdan AAalayhi haqqan fee attawratiwal-injeeli walqur-ani waman awfabiAAahdihi mina Allahi fastabshiroo bibayAAikumuallathee bayaAAtum bihi wathalika huwaalfawzu alAAatheem","juz":11,"page":204},{"s":9,"a":112,"key":"9:112","ar":"ٱلتَّـٰٓئِبُونَ ٱلْعَـٰبِدُونَ ٱلْحَـٰمِدُونَ ٱلسَّـٰٓئِحُونَ ٱلرَّٰكِعُونَ ٱلسَّـٰجِدُونَ ٱلْـَٔامِرُونَ بِٱلْمَعْرُوفِ وَٱلنَّاهُونَ عَنِ ٱلْمُنكَرِ وَٱلْحَـٰفِظُونَ لِحُدُودِ ٱللَّهِ ۗ وَبَشِّرِ ٱلْمُؤْمِنِينَ","en":"[Such believers are] the repentant, the worshippers, the praisers [of Allāh], the travelers [for His cause], those who bow and prostrate [in prayer], those who enjoin what is right and forbid what is wrong, and those who observe the limits [set by] Allāh. And give good tidings to the believers.","tr":"Atta-iboona alAAabidoonaalhamidoona assa-ihoona arrakiAAoonaassajidoona al-amiroona bilmaAAroofiwannahoona AAani almunkari walhafithoonalihudoodi Allahi wabashshiri almu/mineen","juz":11,"page":205},{"s":9,"a":113,"key":"9:113","ar":"مَا كَانَ لِلنَّبِىِّ وَٱلَّذِينَ ءَامَنُوٓا۟ أَن يَسْتَغْفِرُوا۟ لِلْمُشْرِكِينَ وَلَوْ كَانُوٓا۟ أُو۟لِى قُرْبَىٰ مِنۢ بَعْدِ مَا تَبَيَّنَ لَهُمْ أَنَّهُمْ أَصْحَـٰبُ ٱلْجَحِيمِ","en":"It is not for the Prophet and those who have believed to ask forgiveness for the polytheists, even if they were relatives, after it has become clear to them that they are companions of Hellfire.","tr":"Ma kana linnabiyyi wallatheenaamanoo an yastaghfiroo lilmushrikeena walaw kanooolee qurba min baAAdi ma tabayyana lahum annahum as-habualjaheem","juz":11,"page":205},{"s":9,"a":114,"key":"9:114","ar":"وَمَا كَانَ ٱسْتِغْفَارُ إِبْرَٰهِيمَ لِأَبِيهِ إِلَّا عَن مَّوْعِدَةٍ وَعَدَهَآ إِيَّاهُ فَلَمَّا تَبَيَّنَ لَهُۥٓ أَنَّهُۥ عَدُوٌّ لِّلَّهِ تَبَرَّأَ مِنْهُ ۚ إِنَّ إِبْرَٰهِيمَ لَأَوَّٰهٌ حَلِيمٌ","en":"And the request of forgiveness of Abraham for his father was only because of a promise he had made to him. But when it became apparent to him [i.e., Abraham] that he [i.e., the father] was an enemy to Allāh, he disassociated himself from him. Indeed was Abraham compassionate and patient.","tr":"Wama kana istighfaruibraheema li-abeehi illa AAan mawAAidatin waAAadahaiyyahu falamma tabayyana lahu annahu AAaduwwun lillahitabarraa minhu inna ibraheema laawwahun haleem","juz":11,"page":205},{"s":9,"a":115,"key":"9:115","ar":"وَمَا كَانَ ٱللَّهُ لِيُضِلَّ قَوْمًۢا بَعْدَ إِذْ هَدَىٰهُمْ حَتَّىٰ يُبَيِّنَ لَهُم مَّا يَتَّقُونَ ۚ إِنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"And Allāh would not let a people stray after He has guided them until He makes clear to them what they should avoid. Indeed, Allāh is Knowing of all things.","tr":"Wama kana Allahu liyudillaqawman baAAda ith hadahum hattayubayyina lahum ma yattaqoona inna Allaha bikullishay-in AAaleem","juz":11,"page":205},{"s":9,"a":116,"key":"9:116","ar":"إِنَّ ٱللَّهَ لَهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ يُحْىِۦ وَيُمِيتُ ۚ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّ وَلَا نَصِيرٍ","en":"Indeed, to Allāh belongs the dominion of the heavens and the earth; He gives life and causes death. And you have not besides Allāh any protector or any helper.","tr":"Inna Allaha lahu mulku assamawatiwal-ardi yuhyee wayumeetu wama lakummin dooni Allahi min waliyyin wala naseer","juz":11,"page":205},{"s":9,"a":117,"key":"9:117","ar":"لَّقَد تَّابَ ٱللَّهُ عَلَى ٱلنَّبِىِّ وَٱلْمُهَـٰجِرِينَ وَٱلْأَنصَارِ ٱلَّذِينَ ٱتَّبَعُوهُ فِى سَاعَةِ ٱلْعُسْرَةِ مِنۢ بَعْدِ مَا كَادَ يَزِيغُ قُلُوبُ فَرِيقٍ مِّنْهُمْ ثُمَّ تَابَ عَلَيْهِمْ ۚ إِنَّهُۥ بِهِمْ رَءُوفٌ رَّحِيمٌ","en":"Allāh has already forgiven the Prophet and the Muhājireen and the Anṣār who followed him in the hour of difficulty after the hearts of a party of them had almost inclined [to doubt], and then He forgave them. Indeed, He was to them Kind and Merciful.","tr":"Laqad taba Allahu AAalaannabiyyi walmuhajireena wal-ansariallatheena ittabaAAoohu fee saAAati alAAusrati minbaAAdi ma kada yazeeghu quloobu fareeqin minhumthumma taba AAalayhim innahu bihim raoofun raheem","juz":11,"page":205},{"s":9,"a":118,"key":"9:118","ar":"وَعَلَى ٱلثَّلَـٰثَةِ ٱلَّذِينَ خُلِّفُوا۟ حَتَّىٰٓ إِذَا ضَاقَتْ عَلَيْهِمُ ٱلْأَرْضُ بِمَا رَحُبَتْ وَضَاقَتْ عَلَيْهِمْ أَنفُسُهُمْ وَظَنُّوٓا۟ أَن لَّا مَلْجَأَ مِنَ ٱللَّهِ إِلَّآ إِلَيْهِ ثُمَّ تَابَ عَلَيْهِمْ لِيَتُوبُوٓا۟ ۚ إِنَّ ٱللَّهَ هُوَ ٱلتَّوَّابُ ٱلرَّحِيمُ","en":"And [He also forgave] the three who were left alone [i.e., boycotted, regretting their error] to the point that the earth closed in on them in spite of its vastness1 and their souls confined [i.e., anguished] them and they were certain that there is no refuge from Allāh except in Him. Then He turned to them so they could repent. Indeed, Allāh is the Accepting of Repentance,2 the Merciful.","tr":"WaAAala aththalathatiallatheena khullifoo hatta itha daqatAAalayhimu al-ardu bima rahubat wadaqatAAalayhim anfusuhum wathannoo an la maljaamina Allahi illa ilayhi thumma tabaAAalayhim liyatooboo inna Allaha huwa attawwabuarraheem","juz":11,"page":206},{"s":9,"a":119,"key":"9:119","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَكُونُوا۟ مَعَ ٱلصَّـٰدِقِينَ","en":"O you who have believed, fear Allāh and be with those who are true.","tr":"Ya ayyuha allatheena amanooittaqoo Allaha wakoonoo maAAa assadiqeen","juz":11,"page":206},{"s":9,"a":120,"key":"9:120","ar":"مَا كَانَ لِأَهْلِ ٱلْمَدِينَةِ وَمَنْ حَوْلَهُم مِّنَ ٱلْأَعْرَابِ أَن يَتَخَلَّفُوا۟ عَن رَّسُولِ ٱللَّهِ وَلَا يَرْغَبُوا۟ بِأَنفُسِهِمْ عَن نَّفْسِهِۦ ۚ ذَٰلِكَ بِأَنَّهُمْ لَا يُصِيبُهُمْ ظَمَأٌ وَلَا نَصَبٌ وَلَا مَخْمَصَةٌ فِى سَبِيلِ ٱللَّهِ وَلَا يَطَـُٔونَ مَوْطِئًا يَغِيظُ ٱلْكُفَّارَ وَلَا يَنَالُونَ مِنْ عَدُوٍّ نَّيْلًا إِلَّا كُتِبَ لَهُم بِهِۦ عَمَلٌ صَـٰلِحٌ ۚ إِنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ","en":"It was not [proper] for the people of Madīnah and those surrounding them of the bedouins that they remain behind after [the departure of] the Messenger of Allāh or that they prefer themselves over his self.1 That is because they are not afflicted by thirst or fatigue or hunger in the cause of Allāh, nor do they tread on any ground that enrages the disbelievers, nor do they inflict upon an enemy any infliction but that it is registered for them as a righteous deed. Indeed, Allāh does not allow to be lost the reward of the doers of good.","tr":"Ma kana li-ahli almadeenatiwaman hawlahum mina al-aAArabi an yatakhallafooAAan rasooli Allahi wala yarghaboo bi-anfusihimAAan nafsihi thalika bi-annahum la yuseebuhumthamaon wala nasabun walamakhmasatun fee sabeeli Allahi wala yataoonamawti-an yagheethu alkuffara walayanaloona min AAaduwwin naylan illa kutiba lahumbihi AAamalun salihun inna Allaha layudeeAAu ajra almuhsineen","juz":11,"page":206},{"s":9,"a":121,"key":"9:121","ar":"وَلَا يُنفِقُونَ نَفَقَةً صَغِيرَةً وَلَا كَبِيرَةً وَلَا يَقْطَعُونَ وَادِيًا إِلَّا كُتِبَ لَهُمْ لِيَجْزِيَهُمُ ٱللَّهُ أَحْسَنَ مَا كَانُوا۟ يَعْمَلُونَ","en":"Nor do they spend an expenditure, small or large, or cross a valley but that it is registered for them that Allāh may reward them for the best of what they were doing.","tr":"Wala yunfiqoona nafaqatan sagheeratanwala kabeeratan wala yaqtaAAoona wadiyanilla kutiba lahum liyajziyahumu Allahu ahsanama kanoo yaAAmaloon","juz":11,"page":206},{"s":9,"a":122,"key":"9:122","ar":"۞ وَمَا كَانَ ٱلْمُؤْمِنُونَ لِيَنفِرُوا۟ كَآفَّةً ۚ فَلَوْلَا نَفَرَ مِن كُلِّ فِرْقَةٍ مِّنْهُمْ طَآئِفَةٌ لِّيَتَفَقَّهُوا۟ فِى ٱلدِّينِ وَلِيُنذِرُوا۟ قَوْمَهُمْ إِذَا رَجَعُوٓا۟ إِلَيْهِمْ لَعَلَّهُمْ يَحْذَرُونَ","en":"And it is not for the believers to go forth [to battle] all at once. For there should separate from every division of them a group [remaining] to obtain understanding in the religion and warn [i.e., advise] their people when they return to them that they might be cautious.","tr":"Wama kana almu/minoonaliyanfiroo kaffatan falawla nafara min kullifirqatin minhum ta-ifatun liyatafaqqahoo fee addeeniwaliyunthiroo qawmahum itha rajaAAoo ilayhimlaAAallahum yahtharoon","juz":11,"page":206},{"s":9,"a":123,"key":"9:123","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ قَـٰتِلُوا۟ ٱلَّذِينَ يَلُونَكُم مِّنَ ٱلْكُفَّارِ وَلْيَجِدُوا۟ فِيكُمْ غِلْظَةً ۚ وَٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ مَعَ ٱلْمُتَّقِينَ","en":"O you who have believed, fight against those adjacent to you of the disbelievers and let them find in you harshness. And know that Allāh is with the righteous.","tr":"Ya ayyuha allatheena amanooqatiloo allatheena yaloonakum mina alkuffariwalyajidoo feekum ghilthatan waAAlamoo annaAllaha maAAa almuttaqeen","juz":11,"page":207},{"s":9,"a":124,"key":"9:124","ar":"وَإِذَا مَآ أُنزِلَتْ سُورَةٌ فَمِنْهُم مَّن يَقُولُ أَيُّكُمْ زَادَتْهُ هَـٰذِهِۦٓ إِيمَـٰنًا ۚ فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ فَزَادَتْهُمْ إِيمَـٰنًا وَهُمْ يَسْتَبْشِرُونَ","en":"And whenever a sūrah is revealed, there are among them [i.e., the hypocrites] those who say, \"Which of you has this increased in faith?\" As for those who believed, it has increased them in faith, while they are rejoicing.","tr":"Wa-itha ma onzilat sooratunfaminhum man yaqoolu ayyukum zadat-hu hathihi eemananfaamma allatheena amanoo fazadat-humeemanan wahum yastabshiroon","juz":11,"page":207},{"s":9,"a":125,"key":"9:125","ar":"وَأَمَّا ٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌ فَزَادَتْهُمْ رِجْسًا إِلَىٰ رِجْسِهِمْ وَمَاتُوا۟ وَهُمْ كَـٰفِرُونَ","en":"But as for those in whose hearts is disease, it has [only] increased them in evil [in addition] to their evil.1 And they will have died while they are disbelievers.","tr":"Waamma allatheena feequloobihim maradun fazadat-hum rijsan ilarijsihim wamatoo wahum kafiroon","juz":11,"page":207},{"s":9,"a":126,"key":"9:126","ar":"أَوَلَا يَرَوْنَ أَنَّهُمْ يُفْتَنُونَ فِى كُلِّ عَامٍ مَّرَّةً أَوْ مَرَّتَيْنِ ثُمَّ لَا يَتُوبُونَ وَلَا هُمْ يَذَّكَّرُونَ","en":"Do they not see that they are tried every year once or twice but then they do not repent nor do they remember?","tr":"Awa la yarawna annahum yuftanoonafee kulli AAamin marratan aw marratayni thumma layatooboona wala hum yaththakkaroon","juz":11,"page":207},{"s":9,"a":127,"key":"9:127","ar":"وَإِذَا مَآ أُنزِلَتْ سُورَةٌ نَّظَرَ بَعْضُهُمْ إِلَىٰ بَعْضٍ هَلْ يَرَىٰكُم مِّنْ أَحَدٍ ثُمَّ ٱنصَرَفُوا۟ ۚ صَرَفَ ٱللَّهُ قُلُوبَهُم بِأَنَّهُمْ قَوْمٌ لَّا يَفْقَهُونَ","en":"And whenever a sūrah is revealed, they look at each other, [as if saying], \"Does anyone see you?\" and then they dismiss themselves. Allāh has dismissed their hearts because they are a people who do not understand.","tr":"Wa-itha ma onzilat sooratunnathara baAAduhum ila baAAdinhal yarakum min ahadin thumma insarafoo sarafaAllahu quloobahum bi-annahum qawmun la yafqahoon","juz":11,"page":207},{"s":9,"a":128,"key":"9:128","ar":"لَقَدْ جَآءَكُمْ رَسُولٌ مِّنْ أَنفُسِكُمْ عَزِيزٌ عَلَيْهِ مَا عَنِتُّمْ حَرِيصٌ عَلَيْكُم بِٱلْمُؤْمِنِينَ رَءُوفٌ رَّحِيمٌ","en":"There has certainly come to you a Messenger from among yourselves. Grievous to him is what you suffer; [he is] concerned over you [i.e., your guidance] and to the believers is kind and merciful.","tr":"Laqad jaakum rasoolun min anfusikumAAazeezun AAalayhi ma AAanittum hareesunAAalaykum bilmu/mineena raoofun raheem","juz":11,"page":207},{"s":9,"a":129,"key":"9:129","ar":"فَإِن تَوَلَّوْا۟ فَقُلْ حَسْبِىَ ٱللَّهُ لَآ إِلَـٰهَ إِلَّا هُوَ ۖ عَلَيْهِ تَوَكَّلْتُ ۖ وَهُوَ رَبُّ ٱلْعَرْشِ ٱلْعَظِيمِ","en":"But if they turn away, [O Muḥammad], say, \"Sufficient for me is Allāh; there is no deity except Him. On Him I have relied, and He is the Lord of the Great Throne.\"","tr":"Fa-in tawallaw faqul hasbiya Allahula ilaha illa huwa AAalayhi tawakkaltuwahuwa rabbu alAAarshi alAAatheem","juz":11,"page":207},{"s":10,"a":1,"key":"10:1","ar":" الٓر ۚ تِلْكَ ءَايَـٰتُ ٱلْكِتَـٰبِ ٱلْحَكِيمِ","en":"Alif, Lām, Rā.1 These are the verses of the wise2 Book.","tr":"Alif-lam-ra tilka ayatualkitabi alhakeem","juz":11,"page":208},{"s":10,"a":2,"key":"10:2","ar":"أَكَانَ لِلنَّاسِ عَجَبًا أَنْ أَوْحَيْنَآ إِلَىٰ رَجُلٍ مِّنْهُمْ أَنْ أَنذِرِ ٱلنَّاسَ وَبَشِّرِ ٱلَّذِينَ ءَامَنُوٓا۟ أَنَّ لَهُمْ قَدَمَ صِدْقٍ عِندَ رَبِّهِمْ ۗ قَالَ ٱلْكَـٰفِرُونَ إِنَّ هَـٰذَا لَسَـٰحِرٌ مُّبِينٌ","en":"Have the people been amazed that We revealed [revelation] to a man from among them, [saying], \"Warn mankind and give good tidings to those who believe that they will have a [firm] precedence of honor1 with their Lord\"? [But] the disbelievers say, \"Indeed, this is an obvious magician.\"","tr":"Akana linnasi AAajabanan awhayna ila rajulin minhum an anthiriannasa wabashshiri allatheena amanooanna lahum qadama sidqin AAinda rabbihim qala alkafiroonainna hatha lasahirun mubeen","juz":11,"page":208},{"s":10,"a":3,"key":"10:3","ar":"إِنَّ رَبَّكُمُ ٱللَّهُ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ فِى سِتَّةِ أَيَّامٍ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۖ يُدَبِّرُ ٱلْأَمْرَ ۖ مَا مِن شَفِيعٍ إِلَّا مِنۢ بَعْدِ إِذْنِهِۦ ۚ ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ فَٱعْبُدُوهُ ۚ أَفَلَا تَذَكَّرُونَ","en":"Indeed, your Lord is Allāh, who created the heavens and the earth in six days and then established Himself above the Throne,1 arranging the matter [of His creation]. There is no intercessor except after His permission. That is Allāh, your Lord, so worship Him. Then will you not remember?","tr":"Inna rabbakumu Allahu allatheekhalaqa assamawati wal-ardafee sittati ayyamin thumma istawa AAalaalAAarshi yudabbiru al-amra ma min shafeeAAin illamin baAAdi ithnihi thalikumu Allahu rabbukumfaAAbudoohu afala tathakkaroon","juz":11,"page":208},{"s":10,"a":4,"key":"10:4","ar":"إِلَيْهِ مَرْجِعُكُمْ جَمِيعًا ۖ وَعْدَ ٱللَّهِ حَقًّا ۚ إِنَّهُۥ يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ لِيَجْزِىَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ بِٱلْقِسْطِ ۚ وَٱلَّذِينَ كَفَرُوا۟ لَهُمْ شَرَابٌ مِّنْ حَمِيمٍ وَعَذَابٌ أَلِيمٌۢ بِمَا كَانُوا۟ يَكْفُرُونَ","en":"To Him is your return all together. [It is] the promise of Allāh [which is] truth. Indeed, He begins the [process of] creation and then repeats it that He may reward those who have believed and done righteous deeds, in justice. But those who disbelieved will have a drink of scalding water and a painful punishment for what they used to deny.","tr":"Ilayhi marjiAAukum jameeAAan waAAda Allahihaqqan innahu yabdao alkhalqa thumma yuAAeeduhu liyajziyaallatheena amanoo waAAamiloo assalihatibilqisti wallatheena kafaroo lahumsharabun min hameemin waAAathabun aleemunbima kanoo yakfuroon","juz":11,"page":208},{"s":10,"a":5,"key":"10:5","ar":"هُوَ ٱلَّذِى جَعَلَ ٱلشَّمْسَ ضِيَآءً وَٱلْقَمَرَ نُورًا وَقَدَّرَهُۥ مَنَازِلَ لِتَعْلَمُوا۟ عَدَدَ ٱلسِّنِينَ وَٱلْحِسَابَ ۚ مَا خَلَقَ ٱللَّهُ ذَٰلِكَ إِلَّا بِٱلْحَقِّ ۚ يُفَصِّلُ ٱلْـَٔايَـٰتِ لِقَوْمٍ يَعْلَمُونَ","en":"It is He who made the sun a shining light and the moon a derived light and determined for it phases - that you may know the number of years and account [of time]. Allāh has not created this except in truth. He details the signs for a people who know.","tr":"Huwa allathee jaAAala ashshamsadiyaan walqamara nooran waqaddarahu manazilalitaAAlamoo AAadada assineena walhisabama khalaqa Allahu thalika illa bilhaqqiyufassilu al-ayati liqawmin yaAAlamoon","juz":11,"page":208},{"s":10,"a":6,"key":"10:6","ar":"إِنَّ فِى ٱخْتِلَـٰفِ ٱلَّيْلِ وَٱلنَّهَارِ وَمَا خَلَقَ ٱللَّهُ فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ لَـَٔايَـٰتٍ لِّقَوْمٍ يَتَّقُونَ","en":"Indeed, in the alternation of the night and the day and [in] what Allāh has created in the heavens and the earth are signs for a people who fear Allāh.","tr":"Inna fee ikhtilafi allayli wannahariwama khalaqa Allahu fee assamawatiwal-ardi laayatin liqawmin yattaqoon","juz":11,"page":208},{"s":10,"a":7,"key":"10:7","ar":"إِنَّ ٱلَّذِينَ لَا يَرْجُونَ لِقَآءَنَا وَرَضُوا۟ بِٱلْحَيَوٰةِ ٱلدُّنْيَا وَٱطْمَأَنُّوا۟ بِهَا وَٱلَّذِينَ هُمْ عَنْ ءَايَـٰتِنَا غَـٰفِلُونَ","en":"Indeed, those who do not expect the meeting with Us and are satisfied with the life of this world and feel secure therein and those who are heedless of Our signs -","tr":"Inna allatheena la yarjoona liqaanawaradoo bilhayati addunyawatmaannoo biha wallatheenahum AAan ayatina ghafiloon","juz":11,"page":209},{"s":10,"a":8,"key":"10:8","ar":"أُو۟لَـٰٓئِكَ مَأْوَىٰهُمُ ٱلنَّارُ بِمَا كَانُوا۟ يَكْسِبُونَ","en":"For those their refuge will be the Fire because of what they used to earn.","tr":"Ola-ika ma/wahumu annarubima kanoo yaksiboon","juz":11,"page":209},{"s":10,"a":9,"key":"10:9","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ يَهْدِيهِمْ رَبُّهُم بِإِيمَـٰنِهِمْ ۖ تَجْرِى مِن تَحْتِهِمُ ٱلْأَنْهَـٰرُ فِى جَنَّـٰتِ ٱلنَّعِيمِ","en":"Indeed, those who have believed and done righteous deeds - their Lord will guide them because of their faith. Beneath them rivers will flow in the Gardens of Pleasure.","tr":"Inna allatheena amanoowaAAamiloo assalihati yahdeehim rabbuhumbi-eemanihim tajree min tahtihimu al-anharufee jannati annaAAeem","juz":11,"page":209},{"s":10,"a":10,"key":"10:10","ar":"دَعْوَىٰهُمْ فِيهَا سُبْحَـٰنَكَ ٱللَّهُمَّ وَتَحِيَّتُهُمْ فِيهَا سَلَـٰمٌ ۚ وَءَاخِرُ دَعْوَىٰهُمْ أَنِ ٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَـٰلَمِينَ","en":"Their call therein will be, \"Exalted are You, O Allāh,\" and their greeting therein will be, \"Peace.\" And the last of their call will be, \"Praise to Allāh, Lord of the worlds!\"","tr":"DaAAwahum feeha subhanakaallahumma watahiyyatuhum feeha salamunwaakhiru daAAwahum ani alhamdu lillahirabbi alAAalameen","juz":11,"page":209},{"s":10,"a":11,"key":"10:11","ar":"۞ وَلَوْ يُعَجِّلُ ٱللَّهُ لِلنَّاسِ ٱلشَّرَّ ٱسْتِعْجَالَهُم بِٱلْخَيْرِ لَقُضِىَ إِلَيْهِمْ أَجَلُهُمْ ۖ فَنَذَرُ ٱلَّذِينَ لَا يَرْجُونَ لِقَآءَنَا فِى طُغْيَـٰنِهِمْ يَعْمَهُونَ","en":"And if Allāh was to hasten for the people the evil [they invoke]1 as He hastens for them the good, their term would have been ended for them.2 But We leave the ones who do not expect the meeting with Us, in their transgression, wandering blindly.","tr":"Walaw yuAAajjilu Allahu linnasiashsharra istiAAjalahum bilkhayri laqudiyailayhim ajaluhum fanatharu allatheena layarjoona liqaana fee tughyanihimyaAAmahoon","juz":11,"page":209},{"s":10,"a":12,"key":"10:12","ar":"وَإِذَا مَسَّ ٱلْإِنسَـٰنَ ٱلضُّرُّ دَعَانَا لِجَنۢبِهِۦٓ أَوْ قَاعِدًا أَوْ قَآئِمًا فَلَمَّا كَشَفْنَا عَنْهُ ضُرَّهُۥ مَرَّ كَأَن لَّمْ يَدْعُنَآ إِلَىٰ ضُرٍّ مَّسَّهُۥ ۚ كَذَٰلِكَ زُيِّنَ لِلْمُسْرِفِينَ مَا كَانُوا۟ يَعْمَلُونَ","en":"And when affliction touches man, he calls upon Us, whether lying on his side or sitting or standing; but when We remove from him his affliction, he continues [in disobedience] as if he had never called upon Us to [remove] an affliction that touched him. Thus is made pleasing to the transgressors that which they have been doing.","tr":"Wa-itha massa al-insana addurrudaAAana lijanbihi aw qaAAidan aw qa-imanfalamma kashafna AAanhu durrahu marra kaanlam yadAAuna ila durrin massahu kathalikazuyyina lilmusrifeena ma kanoo yaAAmaloon","juz":11,"page":209},{"s":10,"a":13,"key":"10:13","ar":"وَلَقَدْ أَهْلَكْنَا ٱلْقُرُونَ مِن قَبْلِكُمْ لَمَّا ظَلَمُوا۟ ۙ وَجَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَـٰتِ وَمَا كَانُوا۟ لِيُؤْمِنُوا۟ ۚ كَذَٰلِكَ نَجْزِى ٱلْقَوْمَ ٱلْمُجْرِمِينَ","en":"And We had already destroyed generations before you when they wronged, and their messengers had come to them with clear proofs, but they were not to believe. Thus do We recompense the criminal people.","tr":"Walaqad ahlakna alquroona minqablikum lamma thalamoo wajaat-humrusuluhum bilbayyinati wama kanooliyu/minoo kathalika najzee alqawma almujrimeen","juz":11,"page":209},{"s":10,"a":14,"key":"10:14","ar":"ثُمَّ جَعَلْنَـٰكُمْ خَلَـٰٓئِفَ فِى ٱلْأَرْضِ مِنۢ بَعْدِهِمْ لِنَنظُرَ كَيْفَ تَعْمَلُونَ","en":"Then We made you successors in the land after them so that We may observe how you will do.","tr":"Thumma jaAAalnakum khala-ifafee al-ardi min baAAdihim linanthura kayfataAAmaloon","juz":11,"page":209},{"s":10,"a":15,"key":"10:15","ar":"وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَاتُنَا بَيِّنَـٰتٍ ۙ قَالَ ٱلَّذِينَ لَا يَرْجُونَ لِقَآءَنَا ٱئْتِ بِقُرْءَانٍ غَيْرِ هَـٰذَآ أَوْ بَدِّلْهُ ۚ قُلْ مَا يَكُونُ لِىٓ أَنْ أُبَدِّلَهُۥ مِن تِلْقَآئِ نَفْسِىٓ ۖ إِنْ أَتَّبِعُ إِلَّا مَا يُوحَىٰٓ إِلَىَّ ۖ إِنِّىٓ أَخَافُ إِنْ عَصَيْتُ رَبِّى عَذَابَ يَوْمٍ عَظِيمٍ","en":"And when Our verses are recited to them as clear evidences, those who do not expect the meeting with Us say, \"Bring us a Qur’ān other than this or change it.\" Say, [O Muḥammad], \"It is not for me to change it on my own accord. I only follow what is revealed to me. Indeed I fear, if I should disobey my Lord, the punishment of a tremendous Day.\"","tr":"Wa-itha tutla AAalayhim ayatunabayyinatin qala allatheena layarjoona liqaana i/ti biqur-anin ghayri hathaaw baddilhu qul ma yakoonu lee an obaddilahu min tilqa-inafsee in attabiAAu illa ma yooha ilayyainnee akhafu in AAasaytu rabbee AAathabayawmin AAatheem","juz":11,"page":210},{"s":10,"a":16,"key":"10:16","ar":"قُل لَّوْ شَآءَ ٱللَّهُ مَا تَلَوْتُهُۥ عَلَيْكُمْ وَلَآ أَدْرَىٰكُم بِهِۦ ۖ فَقَدْ لَبِثْتُ فِيكُمْ عُمُرًا مِّن قَبْلِهِۦٓ ۚ أَفَلَا تَعْقِلُونَ","en":"Say, \"If Allāh had willed, I would not have recited it to you, nor would He have made it known to you, for I had remained among you a lifetime before it.1 Then will you not reason?\"","tr":"Qul law shaa Allahu matalawtuhu AAalaykum wala adrakum bihi faqadlabithtu feekum AAumuran min qablihi afala taAAqiloon","juz":11,"page":210},{"s":10,"a":17,"key":"10:17","ar":"فَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوْ كَذَّبَ بِـَٔايَـٰتِهِۦٓ ۚ إِنَّهُۥ لَا يُفْلِحُ ٱلْمُجْرِمُونَ","en":"So who is more unjust than he who invents a lie about Allāh or denies His signs? Indeed, the criminals will not succeed.","tr":"Faman athlamu mimmani iftaraAAala Allahi kathiban aw kaththababi-ayatihi innahu la yuflihualmujrimoon","juz":11,"page":210},{"s":10,"a":18,"key":"10:18","ar":"وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَضُرُّهُمْ وَلَا يَنفَعُهُمْ وَيَقُولُونَ هَـٰٓؤُلَآءِ شُفَعَـٰٓؤُنَا عِندَ ٱللَّهِ ۚ قُلْ أَتُنَبِّـُٔونَ ٱللَّهَ بِمَا لَا يَعْلَمُ فِى ٱلسَّمَـٰوَٰتِ وَلَا فِى ٱلْأَرْضِ ۚ سُبْحَـٰنَهُۥ وَتَعَـٰلَىٰ عَمَّا يُشْرِكُونَ","en":"And they worship other than Allāh that which neither harms them nor benefits them, and they say, \"These are our intercessors with Allāh.\" Say, \"Do you inform Allāh of something He does not know in the heavens or on the earth?\" Exalted is He and high above what they associate with Him.","tr":"WayaAAbudoona min dooni Allahi mala yadurruhum wala yanfaAAuhum wayaqooloonahaola-i shufaAAaona AAinda Allahiqul atunabbi-oona Allaha bima la yaAAlamufee assamawati wala fee al-ardisubhanahu wataAAala AAamma yushrikoon","juz":11,"page":210},{"s":10,"a":19,"key":"10:19","ar":"وَمَا كَانَ ٱلنَّاسُ إِلَّآ أُمَّةً وَٰحِدَةً فَٱخْتَلَفُوا۟ ۚ وَلَوْلَا كَلِمَةٌ سَبَقَتْ مِن رَّبِّكَ لَقُضِىَ بَيْنَهُمْ فِيمَا فِيهِ يَخْتَلِفُونَ","en":"And mankind was not but one community [united in religion], but [then] they differed. And if not for a word1 that preceded from your Lord, it would have been judged between them [immediately] concerning that over which they differ.","tr":"Wama kana annasuilla ommatan wahidatan fakhtalafoo walawlakalimatun sabaqat min rabbika laqudiya baynahum feemafeehi yakhtalifoon","juz":11,"page":210},{"s":10,"a":20,"key":"10:20","ar":"وَيَقُولُونَ لَوْلَآ أُنزِلَ عَلَيْهِ ءَايَةٌ مِّن رَّبِّهِۦ ۖ فَقُلْ إِنَّمَا ٱلْغَيْبُ لِلَّهِ فَٱنتَظِرُوٓا۟ إِنِّى مَعَكُم مِّنَ ٱلْمُنتَظِرِينَ","en":"And they say, \"Why is a sign not sent down to him from his Lord?\" So say, \"The unseen is only for Allāh [to administer], so wait; indeed, I am with you among those who wait.\"","tr":"Wayaqooloona lawla onzila AAalayhi ayatunmin rabbihi faqul innama alghaybu lillahi fantathirooinnee maAAakum mina almuntathireen","juz":11,"page":210},{"s":10,"a":21,"key":"10:21","ar":"وَإِذَآ أَذَقْنَا ٱلنَّاسَ رَحْمَةً مِّنۢ بَعْدِ ضَرَّآءَ مَسَّتْهُمْ إِذَا لَهُم مَّكْرٌ فِىٓ ءَايَاتِنَا ۚ قُلِ ٱللَّهُ أَسْرَعُ مَكْرًا ۚ إِنَّ رُسُلَنَا يَكْتُبُونَ مَا تَمْكُرُونَ","en":"And when We give the people a taste of mercy after adversity has touched them, at once they conspire against Our verses. Say, \"Allāh is swifter in strategy.\" Indeed, Our messengers [i.e., angels] record that which you conspire.","tr":"Wa-itha athaqna annasarahmatan min baAAdi darraa massat-hum ithalahum makrun fee ayatina quli AllahuasraAAu makran inna rusulana yaktuboona matamkuroon","juz":11,"page":211},{"s":10,"a":22,"key":"10:22","ar":"هُوَ ٱلَّذِى يُسَيِّرُكُمْ فِى ٱلْبَرِّ وَٱلْبَحْرِ ۖ حَتَّىٰٓ إِذَا كُنتُمْ فِى ٱلْفُلْكِ وَجَرَيْنَ بِهِم بِرِيحٍ طَيِّبَةٍ وَفَرِحُوا۟ بِهَا جَآءَتْهَا رِيحٌ عَاصِفٌ وَجَآءَهُمُ ٱلْمَوْجُ مِن كُلِّ مَكَانٍ وَظَنُّوٓا۟ أَنَّهُمْ أُحِيطَ بِهِمْ ۙ دَعَوُا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ لَئِنْ أَنجَيْتَنَا مِنْ هَـٰذِهِۦ لَنَكُونَنَّ مِنَ ٱلشَّـٰكِرِينَ","en":"It is He who enables you to travel on land and sea until, when you are in ships and they sail with them1 by a good wind and they rejoice therein, there comes a storm wind and the waves come upon them from every place and they expect to be engulfed, they supplicate Allāh, sincere to Him in religion, \"If You should save us from this, we will surely be among the thankful.\"","tr":"Huwa allathee yusayyirukum feealbarri walbahri hatta ithakuntum fee alfulki wajarayna bihim bireehin tayyibatinwafarihoo biha jaat-ha reehunAAasifun wajaahumu almawju min kulli makaninwathannoo annahum oheeta bihimdaAAawoo Allaha mukhliseena lahu addeenala-in anjaytana min hathihi lanakoonanna mina ashshakireen","juz":11,"page":211},{"s":10,"a":23,"key":"10:23","ar":"فَلَمَّآ أَنجَىٰهُمْ إِذَا هُمْ يَبْغُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ ۗ يَـٰٓأَيُّهَا ٱلنَّاسُ إِنَّمَا بَغْيُكُمْ عَلَىٰٓ أَنفُسِكُم ۖ مَّتَـٰعَ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ ثُمَّ إِلَيْنَا مَرْجِعُكُمْ فَنُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ","en":"But when He saves them, at once they commit injustice1 upon the earth without right. O mankind, your injustice is only against yourselves, [being merely] the enjoyment of worldly life. Then to Us is your return, and We will inform you of what you used to do.","tr":"Falamma anjahum ithahum yabghoona fee al-ardi bighayri alhaqqi yaayyuha annasu innama baghyukum AAalaanfusikum mataAAa alhayati addunyathumma ilayna marjiAAukum fanunabbi-okum bimakuntum taAAmaloon","juz":11,"page":211},{"s":10,"a":24,"key":"10:24","ar":"إِنَّمَا مَثَلُ ٱلْحَيَوٰةِ ٱلدُّنْيَا كَمَآءٍ أَنزَلْنَـٰهُ مِنَ ٱلسَّمَآءِ فَٱخْتَلَطَ بِهِۦ نَبَاتُ ٱلْأَرْضِ مِمَّا يَأْكُلُ ٱلنَّاسُ وَٱلْأَنْعَـٰمُ حَتَّىٰٓ إِذَآ أَخَذَتِ ٱلْأَرْضُ زُخْرُفَهَا وَٱزَّيَّنَتْ وَظَنَّ أَهْلُهَآ أَنَّهُمْ قَـٰدِرُونَ عَلَيْهَآ أَتَىٰهَآ أَمْرُنَا لَيْلًا أَوْ نَهَارًا فَجَعَلْنَـٰهَا حَصِيدًا كَأَن لَّمْ تَغْنَ بِٱلْأَمْسِ ۚ كَذَٰلِكَ نُفَصِّلُ ٱلْـَٔايَـٰتِ لِقَوْمٍ يَتَفَكَّرُونَ","en":"The example of [this] worldly life is but like rain which We have sent down from the sky that the plants of the earth absorb - [those] from which men and livestock eat - until, when the earth has taken on its adornment and is beautified and its people suppose that they have capability over it, there comes to it Our command by night or by day, and We make it as a harvest,1 as if it had not flourished yesterday. Thus do We explain in detail the signs for a people who give thought.","tr":"Innama mathalu alhayatiaddunya kama-in anzalnahu mina assama-ifakhtalata bihi nabatu al-ardi mimmaya/kulu annasu wal-anAAamu hattaitha akhathati al-ardu zukhrufaha wazzayyanatwathanna ahluha annahum qadiroonaAAalayha ataha amruna laylan aw naharanfajaAAalnaha haseedan kaan lam taghnabil-amsi kathalika nufassilu al-ayatiliqawmin yatafakkaroon","juz":11,"page":211},{"s":10,"a":25,"key":"10:25","ar":"وَٱللَّهُ يَدْعُوٓا۟ إِلَىٰ دَارِ ٱلسَّلَـٰمِ وَيَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"And Allāh invites to the Home of Peace [i.e., Paradise] and guides whom He wills to a straight path.","tr":"Wallahu yadAAoo ila dariassalami wayahdee man yashao ila siratinmustaqeem","juz":11,"page":211},{"s":10,"a":26,"key":"10:26","ar":"۞ لِّلَّذِينَ أَحْسَنُوا۟ ٱلْحُسْنَىٰ وَزِيَادَةٌ ۖ وَلَا يَرْهَقُ وُجُوهَهُمْ قَتَرٌ وَلَا ذِلَّةٌ ۚ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْجَنَّةِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"For them who have done good is the best [reward] - and extra.1 No darkness will cover their faces, nor humiliation. Those are companions of Paradise; they will abide therein eternally.","tr":"Lillatheena ahsanoo alhusnawaziyadatun wala yarhaqu wujoohahum qatarun walathillatun ola-ika as-habu aljannatihum feeha khalidoon","juz":11,"page":212},{"s":10,"a":27,"key":"10:27","ar":"وَٱلَّذِينَ كَسَبُوا۟ ٱلسَّيِّـَٔاتِ جَزَآءُ سَيِّئَةٍۭ بِمِثْلِهَا وَتَرْهَقُهُمْ ذِلَّةٌ ۖ مَّا لَهُم مِّنَ ٱللَّهِ مِنْ عَاصِمٍ ۖ كَأَنَّمَآ أُغْشِيَتْ وُجُوهُهُمْ قِطَعًا مِّنَ ٱلَّيْلِ مُظْلِمًا ۚ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"But they who have earned [blame for] evil doings - the recompense of an evil deed is its equivalent, and humiliation will cover them. They will have from Allāh no protector. It will be as if their faces are covered with pieces of the night - so dark [are they]. Those are the companions of the Fire; they will abide therein eternally.","tr":"Wallatheena kasaboo assayyi-atijazao sayyi-atin bimithliha watarhaquhum thillatunma lahum mina Allahi min AAasimin kaannamaoghshiyat wujoohuhum qitaAAan mina allayli muthlimanola-ika as-habu annari humfeeha khalidoon","juz":11,"page":212},{"s":10,"a":28,"key":"10:28","ar":"وَيَوْمَ نَحْشُرُهُمْ جَمِيعًا ثُمَّ نَقُولُ لِلَّذِينَ أَشْرَكُوا۟ مَكَانَكُمْ أَنتُمْ وَشُرَكَآؤُكُمْ ۚ فَزَيَّلْنَا بَيْنَهُمْ ۖ وَقَالَ شُرَكَآؤُهُم مَّا كُنتُمْ إِيَّانَا تَعْبُدُونَ","en":"And [mention, O Muḥammad], the Day We will gather them all together - then We will say to those who associated others with Allāh, \"[Remain in] your place, you and your 'partners.'\"1 Then We will separate them,2 and their \"partners\" will say, \"You did not used to worship us,3","tr":"Wayawma nahshuruhum jameeAAan thummanaqoolu lillatheena ashrakoo makanakum antumwashurakaokum fazayyalna baynahum waqalashurakaohum ma kuntum iyyanataAAbudoon","juz":11,"page":212},{"s":10,"a":29,"key":"10:29","ar":"فَكَفَىٰ بِٱللَّهِ شَهِيدًۢا بَيْنَنَا وَبَيْنَكُمْ إِن كُنَّا عَنْ عِبَادَتِكُمْ لَغَـٰفِلِينَ","en":"And sufficient is Allāh as a witness between us and you that we were of your worship unaware.\"","tr":"Fakafa billahishaheedan baynana wabaynakum in kunna AAan AAibadatikumlaghafileen","juz":11,"page":212},{"s":10,"a":30,"key":"10:30","ar":"هُنَالِكَ تَبْلُوا۟ كُلُّ نَفْسٍ مَّآ أَسْلَفَتْ ۚ وَرُدُّوٓا۟ إِلَى ٱللَّهِ مَوْلَىٰهُمُ ٱلْحَقِّ ۖ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ","en":"There, [on that Day], every soul will be put to trial for what it did previously, and they will be returned to Allāh, their master, the Truth, and lost from them is whatever they used to invent.","tr":"Hunalika tabloo kullu nafsin maaslafat waruddoo ila Allahi mawlahumu alhaqqiwadalla AAanhum ma kanoo yaftaroon","juz":11,"page":212},{"s":10,"a":31,"key":"10:31","ar":"قُلْ مَن يَرْزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ أَمَّن يَمْلِكُ ٱلسَّمْعَ وَٱلْأَبْصَـٰرَ وَمَن يُخْرِجُ ٱلْحَىَّ مِنَ ٱلْمَيِّتِ وَيُخْرِجُ ٱلْمَيِّتَ مِنَ ٱلْحَىِّ وَمَن يُدَبِّرُ ٱلْأَمْرَ ۚ فَسَيَقُولُونَ ٱللَّهُ ۚ فَقُلْ أَفَلَا تَتَّقُونَ","en":"Say, \"Who provides for you from the heaven and the earth? Or who controls hearing and sight and who brings the living out of the dead and brings the dead out of the living and who arranges [every] matter?\" They will say, \"Allāh,\" so say, \"Then will you not fear Him?\"","tr":"Qul man yarzuqukum mina assama-iwal-ardi amman yamliku assamAAa wal-absarawaman yukhriju alhayya mina almayyiti wayukhriju almayyitamina alhayyi waman yudabbiru al-amra fasayaqooloona Allahufaqul afala tattaqoon","juz":11,"page":212},{"s":10,"a":32,"key":"10:32","ar":"فَذَٰلِكُمُ ٱللَّهُ رَبُّكُمُ ٱلْحَقُّ ۖ فَمَاذَا بَعْدَ ٱلْحَقِّ إِلَّا ٱلضَّلَـٰلُ ۖ فَأَنَّىٰ تُصْرَفُونَ","en":"For that is Allāh, your Lord, the Truth. And what can be beyond truth except error? So how are you averted?","tr":"Fathalikumu Allahu rabbukumualhaqqu famatha baAAda alhaqqi illa addalalufaanna tusrafoon","juz":11,"page":212},{"s":10,"a":33,"key":"10:33","ar":"كَذَٰلِكَ حَقَّتْ كَلِمَتُ رَبِّكَ عَلَى ٱلَّذِينَ فَسَقُوٓا۟ أَنَّهُمْ لَا يُؤْمِنُونَ","en":"Thus the word [i.e., decree] of your Lord has come into effect upon those who defiantly disobeyed - that they will not believe.","tr":"Kathalika haqqat kalimaturabbika AAala allatheena fasaqoo annahum layu/minoon","juz":11,"page":212},{"s":10,"a":34,"key":"10:34","ar":"قُلْ هَلْ مِن شُرَكَآئِكُم مَّن يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ ۚ قُلِ ٱللَّهُ يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ ۖ فَأَنَّىٰ تُؤْفَكُونَ","en":"Say, \"Are there of your 'partners' any who begins creation and then repeats it?\" Say, \"Allāh begins creation and then repeats it, so how are you deluded?\"","tr":"Qul hal min shuraka-ikum man yabdaoalkhalqa thumma yuAAeeduhu quli Allahu yabdao alkhalqathumma yuAAeeduhu faanna tu/fakoon","juz":11,"page":213},{"s":10,"a":35,"key":"10:35","ar":"قُلْ هَلْ مِن شُرَكَآئِكُم مَّن يَهْدِىٓ إِلَى ٱلْحَقِّ ۚ قُلِ ٱللَّهُ يَهْدِى لِلْحَقِّ ۗ أَفَمَن يَهْدِىٓ إِلَى ٱلْحَقِّ أَحَقُّ أَن يُتَّبَعَ أَمَّن لَّا يَهِدِّىٓ إِلَّآ أَن يُهْدَىٰ ۖ فَمَا لَكُمْ كَيْفَ تَحْكُمُونَ","en":"Say, \"Are there of your 'partners' any who guides to the truth?\" Say, \"Allāh guides to the truth. So is He who guides to the truth more worthy to be followed or he who guides not unless he is guided? Then what is [wrong] with you - how do you judge?\"","tr":"Qul hal min shuraka-ikum man yahdeeila alhaqqi quli Allahu yahdee lilhaqqiafaman yahdee ila alhaqqi ahaqqu anyuttabaAAa amman la yahiddee illa an yuhdafama lakum kayfa tahkumoon","juz":11,"page":213},{"s":10,"a":36,"key":"10:36","ar":"وَمَا يَتَّبِعُ أَكْثَرُهُمْ إِلَّا ظَنًّا ۚ إِنَّ ٱلظَّنَّ لَا يُغْنِى مِنَ ٱلْحَقِّ شَيْـًٔا ۚ إِنَّ ٱللَّهَ عَلِيمٌۢ بِمَا يَفْعَلُونَ","en":"And most of them follow not except assumption. Indeed, assumption avails not against the truth at all. Indeed, Allāh is Knowing of what they do.","tr":"Wama yattabiAAu aktharuhum illathannan inna aththanna layughnee mina alhaqqi shay-an inna Allaha AAaleemunbima yafAAaloon","juz":11,"page":213},{"s":10,"a":37,"key":"10:37","ar":"وَمَا كَانَ هَـٰذَا ٱلْقُرْءَانُ أَن يُفْتَرَىٰ مِن دُونِ ٱللَّهِ وَلَـٰكِن تَصْدِيقَ ٱلَّذِى بَيْنَ يَدَيْهِ وَتَفْصِيلَ ٱلْكِتَـٰبِ لَا رَيْبَ فِيهِ مِن رَّبِّ ٱلْعَـٰلَمِينَ","en":"And it was not [possible] for this Qur’ān to be produced by other than Allāh, but [it is] a confirmation of what was before it and a detailed explanation of the [former] Scripture, about which there is no doubt,1 from the Lord of the worlds.","tr":"Wama kana hatha alqur-anuan yuftara min dooni Allahi walakin tasdeeqaallathee bayna yadayhi watafseela alkitabi larayba feehi min rabbi alAAalameen","juz":11,"page":213},{"s":10,"a":38,"key":"10:38","ar":"أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۖ قُلْ فَأْتُوا۟ بِسُورَةٍ مِّثْلِهِۦ وَٱدْعُوا۟ مَنِ ٱسْتَطَعْتُم مِّن دُونِ ٱللَّهِ إِن كُنتُمْ صَـٰدِقِينَ","en":"Or do they say [about the Prophet (ﷺ)], \"He invented it?\" Say, \"Then bring forth a sūrah like it and call upon [for assistance] whomever you can besides Allāh, if you should be truthful.\"","tr":"Am yaqooloona iftarahu qul fa/toobisooratin mithlihi wadAAoo mani istataAAtum mindooni Allahi in kuntum sadiqeen","juz":11,"page":213},{"s":10,"a":39,"key":"10:39","ar":"بَلْ كَذَّبُوا۟ بِمَا لَمْ يُحِيطُوا۟ بِعِلْمِهِۦ وَلَمَّا يَأْتِهِمْ تَأْوِيلُهُۥ ۚ كَذَٰلِكَ كَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ ۖ فَٱنظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ٱلظَّـٰلِمِينَ","en":"Rather, they have denied that which they encompass not in knowledge and whose interpretation has not yet come to them. Thus did those before them deny. Then observe how was the end of the wrongdoers.","tr":"Bal kaththaboo bima lam yuheetoobiAAilmihi walamma ya/tihim ta/weeluhu kathalika kaththabaallatheena min qablihim fanthurkayfa kana AAaqibatu aththalimeen","juz":11,"page":213},{"s":10,"a":40,"key":"10:40","ar":"وَمِنْهُم مَّن يُؤْمِنُ بِهِۦ وَمِنْهُم مَّن لَّا يُؤْمِنُ بِهِۦ ۚ وَرَبُّكَ أَعْلَمُ بِٱلْمُفْسِدِينَ","en":"And of them are those who believe in it, and of them are those who do not believe in it. And your Lord is most knowing of the corrupters.","tr":"Waminhum man yu/minu bihi waminhum man layu/minu bihi warabbuka aAAlamu bilmufsideen","juz":11,"page":213},{"s":10,"a":41,"key":"10:41","ar":"وَإِن كَذَّبُوكَ فَقُل لِّى عَمَلِى وَلَكُمْ عَمَلُكُمْ ۖ أَنتُم بَرِيٓـُٔونَ مِمَّآ أَعْمَلُ وَأَنَا۠ بَرِىٓءٌ مِّمَّا تَعْمَلُونَ","en":"And if they deny you, [O Muḥammad], then say, \"For me are my deeds, and for you are your deeds. You are disassociated from what I do, and I am disassociated from what you do.\"","tr":"Wa-in kaththabooka faqul lee AAamaleewalakum AAamalukum antum baree-oona mimma aAAmalu waanabaree-on mimma taAAmaloon","juz":11,"page":213},{"s":10,"a":42,"key":"10:42","ar":"وَمِنْهُم مَّن يَسْتَمِعُونَ إِلَيْكَ ۚ أَفَأَنتَ تُسْمِعُ ٱلصُّمَّ وَلَوْ كَانُوا۟ لَا يَعْقِلُونَ","en":"And among them are those who listen to you. But can you cause the deaf to hear [i.e., benefit from this hearing], although they will not use reason?","tr":"Waminhum man yastamiAAoona ilayka afaantatusmiAAu assumma walaw kanoo layaAAqiloon","juz":11,"page":213},{"s":10,"a":43,"key":"10:43","ar":"وَمِنْهُم مَّن يَنظُرُ إِلَيْكَ ۚ أَفَأَنتَ تَهْدِى ٱلْعُمْىَ وَلَوْ كَانُوا۟ لَا يُبْصِرُونَ","en":"And among them are those who look at you. But can you guide the blind although they will not [attempt to] see?","tr":"Waminhum man yanthuru ilaykaafaanta tahdee alAAumya walaw kanoo la yubsiroon","juz":11,"page":214},{"s":10,"a":44,"key":"10:44","ar":"إِنَّ ٱللَّهَ لَا يَظْلِمُ ٱلنَّاسَ شَيْـًٔا وَلَـٰكِنَّ ٱلنَّاسَ أَنفُسَهُمْ يَظْلِمُونَ","en":"Indeed, Allāh does not wrong the people at all, but it is the people who are wronging themselves.","tr":"Inna Allaha la yathlimuannasa shay-an walakinna annasaanfusahum yathlimoon","juz":11,"page":214},{"s":10,"a":45,"key":"10:45","ar":"وَيَوْمَ يَحْشُرُهُمْ كَأَن لَّمْ يَلْبَثُوٓا۟ إِلَّا سَاعَةً مِّنَ ٱلنَّهَارِ يَتَعَارَفُونَ بَيْنَهُمْ ۚ قَدْ خَسِرَ ٱلَّذِينَ كَذَّبُوا۟ بِلِقَآءِ ٱللَّهِ وَمَا كَانُوا۟ مُهْتَدِينَ","en":"And on the Day when He will gather them, [it will be] as if they had not remained [in the world] but an hour of the day, [and] they will know each other. Those will have lost who denied the meeting with Allāh and were not guided.","tr":"Wayawma yahshuruhum kaan lamyalbathoo illa saAAatan mina annahariyataAAarafoona baynahum qad khasira allatheena kaththaboobiliqa-i Allahi wama kanoo muhtadeen","juz":11,"page":214},{"s":10,"a":46,"key":"10:46","ar":"وَإِمَّا نُرِيَنَّكَ بَعْضَ ٱلَّذِى نَعِدُهُمْ أَوْ نَتَوَفَّيَنَّكَ فَإِلَيْنَا مَرْجِعُهُمْ ثُمَّ ٱللَّهُ شَهِيدٌ عَلَىٰ مَا يَفْعَلُونَ","en":"And whether We show you some of what We promise them, [O Muḥammad], or We take you in death, to Us is their return; then, [either way], Allāh is a witness concerning what they are doing.","tr":"Wa-imma nuriyannaka baAAdaallathee naAAiduhum aw natawaffayannaka fa-ilaynamarjiAAuhum thumma Allahu shaheedun AAala mayafAAaloon","juz":11,"page":214},{"s":10,"a":47,"key":"10:47","ar":"وَلِكُلِّ أُمَّةٍ رَّسُولٌ ۖ فَإِذَا جَآءَ رَسُولُهُمْ قُضِىَ بَيْنَهُم بِٱلْقِسْطِ وَهُمْ لَا يُظْلَمُونَ","en":"And for every nation is a messenger. So when their messenger comes,1 it will be judged between them in justice, and they will not be wronged.","tr":"Walikulli ommatin rasoolun fa-itha jaarasooluhum qudiya baynahum bilqisti wahum layuthlamoon","juz":11,"page":214},{"s":10,"a":48,"key":"10:48","ar":"وَيَقُولُونَ مَتَىٰ هَـٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَ","en":"And they say, \"When is [the fulfillment of] this promise, if you should be truthful?\"","tr":"Wayaqooloona mata hathaalwaAAdu in kuntum sadiqeen","juz":11,"page":214},{"s":10,"a":49,"key":"10:49","ar":"قُل لَّآ أَمْلِكُ لِنَفْسِى ضَرًّا وَلَا نَفْعًا إِلَّا مَا شَآءَ ٱللَّهُ ۗ لِكُلِّ أُمَّةٍ أَجَلٌ ۚ إِذَا جَآءَ أَجَلُهُمْ فَلَا يَسْتَـْٔخِرُونَ سَاعَةً ۖ وَلَا يَسْتَقْدِمُونَ","en":"Say, \"I possess not for myself any harm or benefit except what Allāh should will. For every nation is a [specified] term. When their time has come, then they will not remain behind an hour, nor will they precede [it].\"","tr":"Qul la amliku linafsee darranwala nafAAan illa ma shaa Allahulikulli ommatin ajalun itha jaa ajaluhum falayasta/khiroona saAAatan wala yastaqdimoon","juz":11,"page":214},{"s":10,"a":50,"key":"10:50","ar":"قُلْ أَرَءَيْتُمْ إِنْ أَتَىٰكُمْ عَذَابُهُۥ بَيَـٰتًا أَوْ نَهَارًا مَّاذَا يَسْتَعْجِلُ مِنْهُ ٱلْمُجْرِمُونَ","en":"Say, \"Have you considered: if His punishment should come to you by night or by day - for which [aspect] of it would the criminals be impatient?\"1","tr":"Qul araaytum in atakum AAathabuhubayatan aw naharan matha yastaAAjilu minhualmujrimoon","juz":11,"page":214},{"s":10,"a":51,"key":"10:51","ar":"أَثُمَّ إِذَا مَا وَقَعَ ءَامَنتُم بِهِۦٓ ۚ ءَآلْـَٔـٰنَ وَقَدْ كُنتُم بِهِۦ تَسْتَعْجِلُونَ","en":"Then is it that when it has [actually] occurred you will believe in it? Now?1 And you were [once] for it impatient.2","tr":"Athumma itha ma waqaAAa amantumbihi al-ana waqad kuntum bihi tastaAAjiloon","juz":11,"page":214},{"s":10,"a":52,"key":"10:52","ar":"ثُمَّ قِيلَ لِلَّذِينَ ظَلَمُوا۟ ذُوقُوا۟ عَذَابَ ٱلْخُلْدِ هَلْ تُجْزَوْنَ إِلَّا بِمَا كُنتُمْ تَكْسِبُونَ","en":"Then it will be said to those who had wronged, \"Taste the punishment of eternity; are you being recompensed except for what you used to earn?\"","tr":"Thumma qeela lillatheena thalamoothooqoo AAathaba alkhuldi hal tujzawna illabima kuntum taksiboon","juz":11,"page":214},{"s":10,"a":53,"key":"10:53","ar":"۞ وَيَسْتَنۢبِـُٔونَكَ أَحَقٌّ هُوَ ۖ قُلْ إِى وَرَبِّىٓ إِنَّهُۥ لَحَقٌّ ۖ وَمَآ أَنتُم بِمُعْجِزِينَ","en":"And they ask information of you, [O Muḥammad], \"Is it true?\" Say, \"Yes, by my Lord. Indeed, it is truth; and you will not cause failure [to Allāh].\"","tr":"Wayastanbi-oonaka ahaqqun huwa qul eewarabbee innahu lahaqqun wama antum bimuAAjizeen","juz":11,"page":214},{"s":10,"a":54,"key":"10:54","ar":"وَلَوْ أَنَّ لِكُلِّ نَفْسٍ ظَلَمَتْ مَا فِى ٱلْأَرْضِ لَٱفْتَدَتْ بِهِۦ ۗ وَأَسَرُّوا۟ ٱلنَّدَامَةَ لَمَّا رَأَوُا۟ ٱلْعَذَابَ ۖ وَقُضِىَ بَيْنَهُم بِٱلْقِسْطِ ۚ وَهُمْ لَا يُظْلَمُونَ","en":"And if each soul that wronged had everything on earth, it would offer it in ransom. And they will confide regret when they see the punishment; and they will be judged in justice, and they will not be wronged.","tr":"Walaw anna likulli nafsin thalamatma fee al-ardi laftadat bihi waasarroo annadamatalamma raawoo alAAathaba waqudiya baynahum bilqistiwahum la yuthlamoon","juz":11,"page":215},{"s":10,"a":55,"key":"10:55","ar":"أَلَآ إِنَّ لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۗ أَلَآ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ","en":"Unquestionably, to Allāh belongs whatever is in the heavens and the earth. Unquestionably, the promise of Allāh is truth, but most of them do not know.","tr":"Ala inna lillahi ma feeassamawati wal-ardi alainna waAAda Allahi haqqun walakinnaaktharahum la yaAAlamoon","juz":11,"page":215},{"s":10,"a":56,"key":"10:56","ar":"هُوَ يُحْىِۦ وَيُمِيتُ وَإِلَيْهِ تُرْجَعُونَ","en":"He gives life and causes death, and to Him you will be returned.","tr":"Huwa yuhyee wayumeetu wa-ilayhiturjaAAoon","juz":11,"page":215},{"s":10,"a":57,"key":"10:57","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ قَدْ جَآءَتْكُم مَّوْعِظَةٌ مِّن رَّبِّكُمْ وَشِفَآءٌ لِّمَا فِى ٱلصُّدُورِ وَهُدًى وَرَحْمَةٌ لِّلْمُؤْمِنِينَ","en":"O mankind, there has come to you instruction from your Lord and healing for what is in the breasts and guidance and mercy for the believers.","tr":"Ya ayyuha annasuqad jaatkum mawAAithatun min rabbikum washifaonlima fee assudoori wahudan warahmatunlilmu/mineen","juz":11,"page":215},{"s":10,"a":58,"key":"10:58","ar":"قُلْ بِفَضْلِ ٱللَّهِ وَبِرَحْمَتِهِۦ فَبِذَٰلِكَ فَلْيَفْرَحُوا۟ هُوَ خَيْرٌ مِّمَّا يَجْمَعُونَ","en":"Say, \"In the bounty of Allāh and in His mercy - in that let them rejoice; it is better than what they accumulate.\"","tr":"Qul bifadli Allahi wabirahmatihifabithalika falyafrahoo huwa khayrun mimmayajmaAAoon","juz":11,"page":215},{"s":10,"a":59,"key":"10:59","ar":"قُلْ أَرَءَيْتُم مَّآ أَنزَلَ ٱللَّهُ لَكُم مِّن رِّزْقٍ فَجَعَلْتُم مِّنْهُ حَرَامًا وَحَلَـٰلًا قُلْ ءَآللَّهُ أَذِنَ لَكُمْ ۖ أَمْ عَلَى ٱللَّهِ تَفْتَرُونَ","en":"Say, \"Have you seen what Allāh has sent down to you of provision of which you have made [some] lawful and [some] unlawful?\" Say, \"Has Allāh permitted you [to do so], or do you invent [something] about Allāh?\"","tr":"Qul araaytum ma anzala Allahulakum min rizqin fajaAAaltum minhu haraman wahalalanqul allahu athina lakum am AAala Allahitaftaroon","juz":11,"page":215},{"s":10,"a":60,"key":"10:60","ar":"وَمَا ظَنُّ ٱلَّذِينَ يَفْتَرُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ يَوْمَ ٱلْقِيَـٰمَةِ ۗ إِنَّ ٱللَّهَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَشْكُرُونَ","en":"And what will be the supposition of those who invent falsehood about Allāh on the Day of Resurrection?1 Indeed, Allāh is the possessor of bounty for the people, but most of them are not grateful.","tr":"Wama thannu allatheenayaftaroona AAala Allahi alkathiba yawmaalqiyamati inna Allaha lathoo fadlinAAala annasi walakinna aktharahum layashkuroon","juz":11,"page":215},{"s":10,"a":61,"key":"10:61","ar":"وَمَا تَكُونُ فِى شَأْنٍ وَمَا تَتْلُوا۟ مِنْهُ مِن قُرْءَانٍ وَلَا تَعْمَلُونَ مِنْ عَمَلٍ إِلَّا كُنَّا عَلَيْكُمْ شُهُودًا إِذْ تُفِيضُونَ فِيهِ ۚ وَمَا يَعْزُبُ عَن رَّبِّكَ مِن مِّثْقَالِ ذَرَّةٍ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ وَلَآ أَصْغَرَ مِن ذَٰلِكَ وَلَآ أَكْبَرَ إِلَّا فِى كِتَـٰبٍ مُّبِينٍ","en":"And, [O Muḥammad], you are not [engaged] in any matter and do not recite any of the Qur’ān and you [people] do not do any deed except that We are witness over you when you are involved in it. And not absent from your Lord is any [part] of an atom's weight1 within the earth or within the heaven or [anything] smaller than that or greater but that it is in a clear register.","tr":"Wama takoonu fee sha/nin wamatatloo minhu min qur-anin wala taAAmaloona minAAamalin illa kunna AAalaykum shuhoodan ithtufeedoona feehi wama yaAAzubu AAan rabbika minmithqali tharratin fee al-ardi walafee assama-i wala asghara min thalikawala akbara illa fee kitabin mubeen","juz":11,"page":215},{"s":10,"a":62,"key":"10:62","ar":"أَلَآ إِنَّ أَوْلِيَآءَ ٱللَّهِ لَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"Unquestionably, [for] the allies of Allāh there will be no fear concerning them, nor will they grieve -","tr":"Ala inna awliyaa Allahila khawfun AAalayhim wala hum yahzanoon","juz":11,"page":216},{"s":10,"a":63,"key":"10:63","ar":"ٱلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ","en":"Those who believed and were fearing Allāh.","tr":"Allatheena amanoo wakanooyattaqoon","juz":11,"page":216},{"s":10,"a":64,"key":"10:64","ar":"لَهُمُ ٱلْبُشْرَىٰ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَفِى ٱلْـَٔاخِرَةِ ۚ لَا تَبْدِيلَ لِكَلِمَـٰتِ ٱللَّهِ ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"For them are good tidings in the worldly life and in the Hereafter. No change is there in the words [i.e., decrees] of Allāh. That is what is the great attainment.","tr":"Lahumu albushra fee alhayatiaddunya wafee al-akhirati latabdeela likalimati Allahi thalika huwaalfawzu alAAatheem","juz":11,"page":216},{"s":10,"a":65,"key":"10:65","ar":"وَلَا يَحْزُنكَ قَوْلُهُمْ ۘ إِنَّ ٱلْعِزَّةَ لِلَّهِ جَمِيعًا ۚ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"And let not their speech grieve you. Indeed, honor [due to power] belongs to Allāh entirely. He is the Hearing, the Knowing.","tr":"Wala yahzunka qawluhum innaalAAizzata lillahi jameeAAan huwa assameeAAualAAaleem","juz":11,"page":216},{"s":10,"a":66,"key":"10:66","ar":"أَلَآ إِنَّ لِلَّهِ مَن فِى ٱلسَّمَـٰوَٰتِ وَمَن فِى ٱلْأَرْضِ ۗ وَمَا يَتَّبِعُ ٱلَّذِينَ يَدْعُونَ مِن دُونِ ٱللَّهِ شُرَكَآءَ ۚ إِن يَتَّبِعُونَ إِلَّا ٱلظَّنَّ وَإِنْ هُمْ إِلَّا يَخْرُصُونَ","en":"Unquestionably, to Allāh belongs whoever is in the heavens and whoever is on the earth. And those who invoke other than Allāh do not [actually] follow [His] \"partners.\" They follow not except assumption, and they are not but misjudging.","tr":"Ala inna lillahi man fee assamawatiwaman fee al-ardi wama yattabiAAu allatheenayadAAoona min dooni Allahi shurakaa inyattabiAAoona illa aththanna wa-inhum illa yakhrusoon","juz":11,"page":216},{"s":10,"a":67,"key":"10:67","ar":"هُوَ ٱلَّذِى جَعَلَ لَكُمُ ٱلَّيْلَ لِتَسْكُنُوا۟ فِيهِ وَٱلنَّهَارَ مُبْصِرًا ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يَسْمَعُونَ","en":"It is He who made for you the night to rest therein and the day, giving sight.1 Indeed in that are signs for a people who listen.","tr":"Huwa allathee jaAAala lakumu allaylalitaskunoo feehi wannahara mubsiran innafee thalika laayatin liqawmin yasmaAAoon","juz":11,"page":216},{"s":10,"a":68,"key":"10:68","ar":"قَالُوا۟ ٱتَّخَذَ ٱللَّهُ وَلَدًا ۗ سُبْحَـٰنَهُۥ ۖ هُوَ ٱلْغَنِىُّ ۖ لَهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ إِنْ عِندَكُم مِّن سُلْطَـٰنٍۭ بِهَـٰذَآ ۚ أَتَقُولُونَ عَلَى ٱللَّهِ مَا لَا تَعْلَمُونَ","en":"They1 have said, \"Allāh has taken a son.\" Exalted is He; He is the [one] Free of need. To Him belongs whatever is in the heavens and whatever is in the earth. You have no authority2 for this [claim]. Do you say about Allāh that which you do not know?","tr":"Qaloo ittakhatha Allahuwaladan subhanahu huwa alghaniyyu lahu ma fee assamawatiwama fee al-ardi in AAindakum min sultaninbihatha ataqooloona AAala Allahi ma lataAAlamoon","juz":11,"page":216},{"s":10,"a":69,"key":"10:69","ar":"قُلْ إِنَّ ٱلَّذِينَ يَفْتَرُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ لَا يُفْلِحُونَ","en":"Say, \"Indeed, those who invent falsehood about Allāh will not succeed.\"","tr":"Qul inna allatheena yaftaroona AAalaAllahi alkathiba la yuflihoon","juz":11,"page":216},{"s":10,"a":70,"key":"10:70","ar":"مَتَـٰعٌ فِى ٱلدُّنْيَا ثُمَّ إِلَيْنَا مَرْجِعُهُمْ ثُمَّ نُذِيقُهُمُ ٱلْعَذَابَ ٱلشَّدِيدَ بِمَا كَانُوا۟ يَكْفُرُونَ","en":"[For them is brief] enjoyment in this world; then to Us is their return; then We will make them taste the severe punishment because they used to disbelieve.","tr":"MataAAun fee addunyathumma ilayna marjiAAuhum thumma nutheequhumu alAAathabaashshadeeda bima kanoo yakfuroon","juz":11,"page":216},{"s":10,"a":71,"key":"10:71","ar":"۞ وَٱتْلُ عَلَيْهِمْ نَبَأَ نُوحٍ إِذْ قَالَ لِقَوْمِهِۦ يَـٰقَوْمِ إِن كَانَ كَبُرَ عَلَيْكُم مَّقَامِى وَتَذْكِيرِى بِـَٔايَـٰتِ ٱللَّهِ فَعَلَى ٱللَّهِ تَوَكَّلْتُ فَأَجْمِعُوٓا۟ أَمْرَكُمْ وَشُرَكَآءَكُمْ ثُمَّ لَا يَكُنْ أَمْرُكُمْ عَلَيْكُمْ غُمَّةً ثُمَّ ٱقْضُوٓا۟ إِلَىَّ وَلَا تُنظِرُونِ","en":"And recite to them the news of Noah, when he said to his people, \"O my people, if my residence and my reminding of the signs of Allāh has become burdensome upon you - then I have relied upon Allāh. So resolve upon your plan and [call upon] your associates. Then let not your plan be obscure to you.1 Then carry it out upon me and do not give me respite.","tr":"Watlu AAalayhim nabaa noohinith qala liqawmihi ya qawmi in kanakabura AAalaykum maqamee watathkeeree bi-ayatiAllahi faAAala Allahi tawakkaltu faajmiAAooamrakum washurakaakum thumma la yakun amrukumAAalaykum ghummatan thumma iqdoo ilayya wala tunthiroon","juz":11,"page":217},{"s":10,"a":72,"key":"10:72","ar":"فَإِن تَوَلَّيْتُمْ فَمَا سَأَلْتُكُم مِّنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَى ٱللَّهِ ۖ وَأُمِرْتُ أَنْ أَكُونَ مِنَ ٱلْمُسْلِمِينَ","en":"And if you turn away [from my advice] - then no payment have I asked of you. My reward is only from Allāh, and I have been commanded to be of the Muslims [i.e., those who submit to Allāh].\"","tr":"Fa-in tawallaytum fama saaltukum minajrin in ajriya illa AAala Allahi waomirtuan akoona mina almuslimeen","juz":11,"page":217},{"s":10,"a":73,"key":"10:73","ar":"فَكَذَّبُوهُ فَنَجَّيْنَـٰهُ وَمَن مَّعَهُۥ فِى ٱلْفُلْكِ وَجَعَلْنَـٰهُمْ خَلَـٰٓئِفَ وَأَغْرَقْنَا ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا ۖ فَٱنظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُنذَرِينَ","en":"And they denied him, so We saved him and those with him in the ship and made them successors, and We drowned those who denied Our signs. Then see how was the end of those who were warned.","tr":"Fakaththaboohu fanajjaynahuwaman maAAahu fee alfulki wajaAAalnahum khala-ifawaaghraqna allatheena kaththaboo bi-ayatinafanthur kayfa kana AAaqibatualmunthareen","juz":11,"page":217},{"s":10,"a":74,"key":"10:74","ar":"ثُمَّ بَعَثْنَا مِنۢ بَعْدِهِۦ رُسُلًا إِلَىٰ قَوْمِهِمْ فَجَآءُوهُم بِٱلْبَيِّنَـٰتِ فَمَا كَانُوا۟ لِيُؤْمِنُوا۟ بِمَا كَذَّبُوا۟ بِهِۦ مِن قَبْلُ ۚ كَذَٰلِكَ نَطْبَعُ عَلَىٰ قُلُوبِ ٱلْمُعْتَدِينَ","en":"Then We sent after him messengers to their peoples, and they came to them with clear proofs. But they were not to believe in that which they had denied before.1 Thus We seal over the hearts of the transgressors.","tr":"Thumma baAAathna min baAAdihi rusulanila qawmihim fajaoohum bilbayyinatifama kanoo liyu/minoo bima kaththaboobihi min qablu kathalika natbaAAu AAalaquloobi almuAAtadeen","juz":11,"page":217},{"s":10,"a":75,"key":"10:75","ar":"ثُمَّ بَعَثْنَا مِنۢ بَعْدِهِم مُّوسَىٰ وَهَـٰرُونَ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ بِـَٔايَـٰتِنَا فَٱسْتَكْبَرُوا۟ وَكَانُوا۟ قَوْمًا مُّجْرِمِينَ","en":"Then We sent after them Moses and Aaron to Pharaoh and his establishment with Our signs, but they behaved arrogantly and were a criminal people.","tr":"Thumma baAAathna min baAAdihim moosawaharoona ila firAAawna wamala-ihi bi-ayatinafastakbaroo wakanoo qawman mujrimeen","juz":11,"page":217},{"s":10,"a":76,"key":"10:76","ar":"فَلَمَّا جَآءَهُمُ ٱلْحَقُّ مِنْ عِندِنَا قَالُوٓا۟ إِنَّ هَـٰذَا لَسِحْرٌ مُّبِينٌ","en":"So when there came to them the truth from Us, they said, \"Indeed, this is obvious magic.\"","tr":"Falamma jaahumu alhaqqumin AAindina qaloo inna hatha lasihrunmubeen","juz":11,"page":217},{"s":10,"a":77,"key":"10:77","ar":"قَالَ مُوسَىٰٓ أَتَقُولُونَ لِلْحَقِّ لَمَّا جَآءَكُمْ ۖ أَسِحْرٌ هَـٰذَا وَلَا يُفْلِحُ ٱلسَّـٰحِرُونَ","en":"Moses said, \"Do you say [thus] about the truth when it has come to you? Is this magic? But magicians will not succeed.\"","tr":"Qala moosa ataqooloona lilhaqqilamma jaakum asihrun hatha walayuflihu assahiroon","juz":11,"page":217},{"s":10,"a":78,"key":"10:78","ar":"قَالُوٓا۟ أَجِئْتَنَا لِتَلْفِتَنَا عَمَّا وَجَدْنَا عَلَيْهِ ءَابَآءَنَا وَتَكُونَ لَكُمَا ٱلْكِبْرِيَآءُ فِى ٱلْأَرْضِ وَمَا نَحْنُ لَكُمَا بِمُؤْمِنِينَ","en":"They said, \"Have you come to us to turn us away from that upon which we found our fathers and so that you two may have grandeur in the land? And we are not believers in you.\"","tr":"Qaloo aji/tana litalfitanaAAamma wajadna AAalayhi abaanawatakoona lakuma alkibriyao fee al-ardi wamanahnu lakuma bimu/mineen","juz":11,"page":217},{"s":10,"a":79,"key":"10:79","ar":"وَقَالَ فِرْعَوْنُ ٱئْتُونِى بِكُلِّ سَـٰحِرٍ عَلِيمٍ","en":"And Pharaoh said, \"Bring to me every learned magician.\"","tr":"Waqala firAAawnu i/toonee bikulli sahirinAAaleem","juz":11,"page":218},{"s":10,"a":80,"key":"10:80","ar":"فَلَمَّا جَآءَ ٱلسَّحَرَةُ قَالَ لَهُم مُّوسَىٰٓ أَلْقُوا۟ مَآ أَنتُم مُّلْقُونَ","en":"So when the magicians came, Moses said to them, \"Throw down whatever you will throw.\"","tr":"Falamma jaa assaharatuqala lahum moosa alqoo ma antum mulqoon","juz":11,"page":218},{"s":10,"a":81,"key":"10:81","ar":"فَلَمَّآ أَلْقَوْا۟ قَالَ مُوسَىٰ مَا جِئْتُم بِهِ ٱلسِّحْرُ ۖ إِنَّ ٱللَّهَ سَيُبْطِلُهُۥٓ ۖ إِنَّ ٱللَّهَ لَا يُصْلِحُ عَمَلَ ٱلْمُفْسِدِينَ","en":"And when they had thrown, Moses said, \"What you have brought is [only] magic. Indeed, Allāh will expose its worthlessness. Indeed, Allāh does not amend the work of corrupters.","tr":"Falamma alqaw qala moosama ji/tum bihi assihru inna Allahasayubtiluhu inna Allaha la yuslihuAAamala almufsideen","juz":11,"page":218},{"s":10,"a":82,"key":"10:82","ar":"وَيُحِقُّ ٱللَّهُ ٱلْحَقَّ بِكَلِمَـٰتِهِۦ وَلَوْ كَرِهَ ٱلْمُجْرِمُونَ","en":"And Allāh will establish the truth by His words, even if the criminals dislike it.\"","tr":"Wayuhiqqu Allahu alhaqqabikalimatihi walaw kariha almujrimoon","juz":11,"page":218},{"s":10,"a":83,"key":"10:83","ar":"فَمَآ ءَامَنَ لِمُوسَىٰٓ إِلَّا ذُرِّيَّةٌ مِّن قَوْمِهِۦ عَلَىٰ خَوْفٍ مِّن فِرْعَوْنَ وَمَلَإِي۟هِمْ أَن يَفْتِنَهُمْ ۚ وَإِنَّ فِرْعَوْنَ لَعَالٍ فِى ٱلْأَرْضِ وَإِنَّهُۥ لَمِنَ ٱلْمُسْرِفِينَ","en":"But no one believed Moses, except [some] offspring [i.e., youths] among his people, for fear of Pharaoh and his establishment that they would persecute them. And indeed, Pharaoh was haughty within the land, and indeed, he was of the transgressors.","tr":"Fama amana limoosa illathurriyyatun min qawmihi AAala khawfin minfirAAawna wamala-ihim an yaftinahum wa-inna firAAawna laAAalinfee al-ardi wa-innahu lamina almusrifeen","juz":11,"page":218},{"s":10,"a":84,"key":"10:84","ar":"وَقَالَ مُوسَىٰ يَـٰقَوْمِ إِن كُنتُمْ ءَامَنتُم بِٱللَّهِ فَعَلَيْهِ تَوَكَّلُوٓا۟ إِن كُنتُم مُّسْلِمِينَ","en":"And Moses said, \"O my people, if you have believed in Allāh, then rely upon Him, if you should be Muslims [i.e., submitting to Him].\"","tr":"Waqala moosa ya qawmiin kuntum amantum billahi faAAalayhitawakkaloo in kuntum muslimeen","juz":11,"page":218},{"s":10,"a":85,"key":"10:85","ar":"فَقَالُوا۟ عَلَى ٱللَّهِ تَوَكَّلْنَا رَبَّنَا لَا تَجْعَلْنَا فِتْنَةً لِّلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"So they said, \"Upon Allāh do we rely. Our Lord, make us not [objects of] trial for the wrongdoing people","tr":"Faqaloo AAala Allahitawakkalna rabbana la tajAAalnafitnatan lilqawmi aththalimeen","juz":11,"page":218},{"s":10,"a":86,"key":"10:86","ar":"وَنَجِّنَا بِرَحْمَتِكَ مِنَ ٱلْقَوْمِ ٱلْكَـٰفِرِينَ","en":"And save us by Your mercy from the disbelieving people.\"","tr":"Wanajjina birahmatika minaalqawmi alkafireen","juz":11,"page":218},{"s":10,"a":87,"key":"10:87","ar":"وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰ وَأَخِيهِ أَن تَبَوَّءَا لِقَوْمِكُمَا بِمِصْرَ بُيُوتًا وَٱجْعَلُوا۟ بُيُوتَكُمْ قِبْلَةً وَأَقِيمُوا۟ ٱلصَّلَوٰةَ ۗ وَبَشِّرِ ٱلْمُؤْمِنِينَ","en":"And We inspired to Moses and his brother, \"Settle your people in Egypt in houses and make your houses [facing the] qiblah1 and establish prayer and give good tidings to the believers.\"","tr":"Waawhayna ila moosawaakheehi an tabawwaa liqawmikuma bimisrabuyootan wajAAaloo buyootakum qiblatan waaqeemoo assalatawabashshiri almu/mineen","juz":11,"page":218},{"s":10,"a":88,"key":"10:88","ar":"وَقَالَ مُوسَىٰ رَبَّنَآ إِنَّكَ ءَاتَيْتَ فِرْعَوْنَ وَمَلَأَهُۥ زِينَةً وَأَمْوَٰلًا فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا رَبَّنَا لِيُضِلُّوا۟ عَن سَبِيلِكَ ۖ رَبَّنَا ٱطْمِسْ عَلَىٰٓ أَمْوَٰلِهِمْ وَٱشْدُدْ عَلَىٰ قُلُوبِهِمْ فَلَا يُؤْمِنُوا۟ حَتَّىٰ يَرَوُا۟ ٱلْعَذَابَ ٱلْأَلِيمَ","en":"And Moses said, \"Our Lord, indeed You have given Pharaoh and his establishment splendor and wealth in the worldly life, our Lord, that they may lead [men] astray from Your way. Our Lord, obliterate their wealth and harden their hearts so that they will not believe until they see the painful punishment.\"","tr":"Waqala moosa rabbanainnaka atayta firAAawna wamalaahu zeenatan waamwalanfee alhayati addunya rabbanaliyudilloo AAan sabeelika rabbana itmis AAalaamwalihim washdud AAala quloobihim falayu/minoo hatta yarawoo alAAathaba al-aleem","juz":11,"page":218},{"s":10,"a":89,"key":"10:89","ar":"قَالَ قَدْ أُجِيبَت دَّعْوَتُكُمَا فَٱسْتَقِيمَا وَلَا تَتَّبِعَآنِّ سَبِيلَ ٱلَّذِينَ لَا يَعْلَمُونَ","en":"[Allāh] said, \"Your supplication has been answered.\"1 So remain on a right course and follow not the way of those who do not know.\"","tr":"Qala qad ojeebat daAAwatukumafastaqeema wala tattabiAAannisabeela allatheena la yaAAlamoon","juz":11,"page":219},{"s":10,"a":90,"key":"10:90","ar":"۞ وَجَـٰوَزْنَا بِبَنِىٓ إِسْرَٰٓءِيلَ ٱلْبَحْرَ فَأَتْبَعَهُمْ فِرْعَوْنُ وَجُنُودُهُۥ بَغْيًا وَعَدْوًا ۖ حَتَّىٰٓ إِذَآ أَدْرَكَهُ ٱلْغَرَقُ قَالَ ءَامَنتُ أَنَّهُۥ لَآ إِلَـٰهَ إِلَّا ٱلَّذِىٓ ءَامَنَتْ بِهِۦ بَنُوٓا۟ إِسْرَٰٓءِيلَ وَأَنَا۠ مِنَ ٱلْمُسْلِمِينَ","en":"And We took the Children of Israel across the sea, and Pharaoh and his soldiers pursued them in tyranny and enmity until, when drowning overtook him, he said, \"I believe that there is no deity except that in whom the Children of Israel believe, and I am of the Muslims.\"","tr":"Wajawazna bibanee isra-eelaalbahra faatbaAAahum firAAawnu wajunooduhu baghyanwaAAadwan hatta itha adrakahu algharaqu qalaamantu annahu la ilaha illa allatheeamanat bihi banoo isra-eela waana minaalmuslimeen","juz":11,"page":219},{"s":10,"a":91,"key":"10:91","ar":"ءَآلْـَٔـٰنَ وَقَدْ عَصَيْتَ قَبْلُ وَكُنتَ مِنَ ٱلْمُفْسِدِينَ","en":"Now? And you had disobeyed [Him] before and were of the corrupters?","tr":"Al-ana waqad AAasaytaqablu wakunta mina almufsideen","juz":11,"page":219},{"s":10,"a":92,"key":"10:92","ar":"فَٱلْيَوْمَ نُنَجِّيكَ بِبَدَنِكَ لِتَكُونَ لِمَنْ خَلْفَكَ ءَايَةً ۚ وَإِنَّ كَثِيرًا مِّنَ ٱلنَّاسِ عَنْ ءَايَـٰتِنَا لَغَـٰفِلُونَ","en":"So today We will save you in body1 that you may be to those who succeed you a sign. And indeed, many among the people, of Our signs, are heedless.","tr":"Falyawma nunajjeeka bibadanikalitakoona liman khalfaka ayatan wa-inna katheeran mina annasiAAan ayatina laghafiloon","juz":11,"page":219},{"s":10,"a":93,"key":"10:93","ar":"وَلَقَدْ بَوَّأْنَا بَنِىٓ إِسْرَٰٓءِيلَ مُبَوَّأَ صِدْقٍ وَرَزَقْنَـٰهُم مِّنَ ٱلطَّيِّبَـٰتِ فَمَا ٱخْتَلَفُوا۟ حَتَّىٰ جَآءَهُمُ ٱلْعِلْمُ ۚ إِنَّ رَبَّكَ يَقْضِى بَيْنَهُمْ يَوْمَ ٱلْقِيَـٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ","en":"And We had certainly settled the Children of Israel in an agreeable settlement and provided them with good things. And they did not differ until [after] knowledge had come to them. Indeed, your Lord will judge between them on the Day of Resurrection concerning that over which they used to differ.","tr":"Walaqad bawwa/na banee isra-eelamubawwaa sidqin warazaqnahum mina attayyibatifama ikhtalafoo hatta jaahumualAAilmu inna rabbaka yaqdee baynahum yawma alqiyamatifeema kanoo feehi yakhtalifoon","juz":11,"page":219},{"s":10,"a":94,"key":"10:94","ar":"فَإِن كُنتَ فِى شَكٍّ مِّمَّآ أَنزَلْنَآ إِلَيْكَ فَسْـَٔلِ ٱلَّذِينَ يَقْرَءُونَ ٱلْكِتَـٰبَ مِن قَبْلِكَ ۚ لَقَدْ جَآءَكَ ٱلْحَقُّ مِن رَّبِّكَ فَلَا تَكُونَنَّ مِنَ ٱلْمُمْتَرِينَ","en":"So if you are in doubt, [O Muḥammad], about that which We have revealed to you, then ask those who have been reading the Scripture before you. The truth has certainly come to you from your Lord, so never be among the doubters.","tr":"Fa-in kunta fee shakkin mimma anzalnnailayka fas-ali allatheena yaqraoona alkitabamin qablika laqad jaaka alhaqqu min rabbika falatakoonanna mina almumtareen","juz":11,"page":219},{"s":10,"a":95,"key":"10:95","ar":"وَلَا تَكُونَنَّ مِنَ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِ ٱللَّهِ فَتَكُونَ مِنَ ٱلْخَـٰسِرِينَ","en":"And never be of those who deny the signs of Allāh and [thus] be among the losers.1","tr":"Wala takoonanna mina allatheenakaththaboo bi-ayati Allahi fatakoonamina alkhasireen","juz":11,"page":219},{"s":10,"a":96,"key":"10:96","ar":"إِنَّ ٱلَّذِينَ حَقَّتْ عَلَيْهِمْ كَلِمَتُ رَبِّكَ لَا يُؤْمِنُونَ","en":"Indeed, those upon whom the word [i.e., decree] of your Lord has come into effect will not believe,","tr":"Inna allatheena haqqatAAalayhim kalimatu rabbika la yu/minoon","juz":11,"page":219},{"s":10,"a":97,"key":"10:97","ar":"وَلَوْ جَآءَتْهُمْ كُلُّ ءَايَةٍ حَتَّىٰ يَرَوُا۟ ٱلْعَذَابَ ٱلْأَلِيمَ","en":"Even if every sign should come to them, until they see the painful punishment.","tr":"Walaw jaat-hum kullu ayatin hattayarawoo alAAathaba al-aleem","juz":11,"page":219},{"s":10,"a":98,"key":"10:98","ar":"فَلَوْلَا كَانَتْ قَرْيَةٌ ءَامَنَتْ فَنَفَعَهَآ إِيمَـٰنُهَآ إِلَّا قَوْمَ يُونُسَ لَمَّآ ءَامَنُوا۟ كَشَفْنَا عَنْهُمْ عَذَابَ ٱلْخِزْىِ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَمَتَّعْنَـٰهُمْ إِلَىٰ حِينٍ","en":"Then has there not been a [single] city that believed so its faith benefited it except the people of Jonah? When they believed, We removed from them the punishment of disgrace in worldly life and gave them enjoyment [i.e., provision] for a time.","tr":"Falawla kanat qaryatun amanatfanafaAAaha eemanuha illa qawmayoonusa lamma amanoo kashafna AAanhum AAathabaalkhizyi fee alhayati addunyawamattaAAnahum ila heen","juz":11,"page":220},{"s":10,"a":99,"key":"10:99","ar":"وَلَوْ شَآءَ رَبُّكَ لَـَٔامَنَ مَن فِى ٱلْأَرْضِ كُلُّهُمْ جَمِيعًا ۚ أَفَأَنتَ تُكْرِهُ ٱلنَّاسَ حَتَّىٰ يَكُونُوا۟ مُؤْمِنِينَ","en":"And had your Lord willed, those on earth would have believed - all of them entirely. Then, [O Muḥammad], would you compel the people in order that they become believers?","tr":"Walaw shaa rabbuka laamana manfee al-ardi kulluhum jameeAAan afaanta tukrihu annasahatta yakoonoo mu/mineen","juz":11,"page":220},{"s":10,"a":100,"key":"10:100","ar":"وَمَا كَانَ لِنَفْسٍ أَن تُؤْمِنَ إِلَّا بِإِذْنِ ٱللَّهِ ۚ وَيَجْعَلُ ٱلرِّجْسَ عَلَى ٱلَّذِينَ لَا يَعْقِلُونَ","en":"And it is not for a soul [i.e., anyone] to believe except by permission of Allāh, and He will place defilement1 upon those who will not use reason.","tr":"Wama kana linafsin an tu/minailla bi-ithni Allahi wayajAAalu arrijsaAAala allatheena la yaAAqiloon","juz":11,"page":220},{"s":10,"a":101,"key":"10:101","ar":"قُلِ ٱنظُرُوا۟ مَاذَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَمَا تُغْنِى ٱلْـَٔايَـٰتُ وَٱلنُّذُرُ عَن قَوْمٍ لَّا يُؤْمِنُونَ","en":"Say, \"Observe what is in the heavens and the earth.\" But of no avail will be signs or warners to a people who do not believe.","tr":"Quli onthuroo mathafee assamawati wal-ardi wamatughnee al-ayatu wannuthuru AAanqawmin la yu/minoon","juz":11,"page":220},{"s":10,"a":102,"key":"10:102","ar":"فَهَلْ يَنتَظِرُونَ إِلَّا مِثْلَ أَيَّامِ ٱلَّذِينَ خَلَوْا۟ مِن قَبْلِهِمْ ۚ قُلْ فَٱنتَظِرُوٓا۟ إِنِّى مَعَكُم مِّنَ ٱلْمُنتَظِرِينَ","en":"So do they wait except for like [what occurred in] the days of those who passed on before them? Say, \"Then wait; indeed, I am with you among those who wait.\"","tr":"Fahal yantathiroona illamithla ayyami allatheena khalaw min qablihim qul fantathirooinnee maAAakum mina almuntathireen","juz":11,"page":220},{"s":10,"a":103,"key":"10:103","ar":"ثُمَّ نُنَجِّى رُسُلَنَا وَٱلَّذِينَ ءَامَنُوا۟ ۚ كَذَٰلِكَ حَقًّا عَلَيْنَا نُنجِ ٱلْمُؤْمِنِينَ","en":"Then We will save Our messengers and those who have believed. Thus, it is an obligation upon Us that We save the believers.1","tr":"Thumma nunajjee rusulana wallatheenaamanoo kathalika haqqan AAalaynanunjee almu/mineen","juz":11,"page":220},{"s":10,"a":104,"key":"10:104","ar":"قُلْ يَـٰٓأَيُّهَا ٱلنَّاسُ إِن كُنتُمْ فِى شَكٍّ مِّن دِينِى فَلَآ أَعْبُدُ ٱلَّذِينَ تَعْبُدُونَ مِن دُونِ ٱللَّهِ وَلَـٰكِنْ أَعْبُدُ ٱللَّهَ ٱلَّذِى يَتَوَفَّىٰكُمْ ۖ وَأُمِرْتُ أَنْ أَكُونَ مِنَ ٱلْمُؤْمِنِينَ","en":"Say, [O Muḥammad], \"O people, if you are in doubt as to my religion - then I do not worship those which you worship besides Allāh; but I worship Allāh, who causes your death. And I have been commanded to be of the believers","tr":"Qul ya ayyuha annasuin kuntum fee shakkin min deenee fala aAAbudu allatheenataAAbudoona min dooni Allahi walakin aAAbudu Allahaallathee yatawaffakum waomirtu an akoona minaalmu/mineen","juz":11,"page":220},{"s":10,"a":105,"key":"10:105","ar":"وَأَنْ أَقِمْ وَجْهَكَ لِلدِّينِ حَنِيفًا وَلَا تَكُونَنَّ مِنَ ٱلْمُشْرِكِينَ","en":"And [commanded], 'Direct your face [i.e., self] toward the religion, inclining to truth, and never be of those who associate others with Allāh;","tr":"Waan aqim wajhaka liddeeni haneefanwala takoonanna mina almushrikeen","juz":11,"page":220},{"s":10,"a":106,"key":"10:106","ar":"وَلَا تَدْعُ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُكَ وَلَا يَضُرُّكَ ۖ فَإِن فَعَلْتَ فَإِنَّكَ إِذًا مِّنَ ٱلظَّـٰلِمِينَ","en":"And do not invoke1 besides Allāh that which neither benefits you nor harms you, for if you did, then indeed you would be of the wrongdoers.'\"2","tr":"Wala tadAAu min dooni Allahima la yanfaAAuka wala yadurruka fa-infaAAalta fa-innaka ithan mina aththalimeen","juz":11,"page":220},{"s":10,"a":107,"key":"10:107","ar":"وَإِن يَمْسَسْكَ ٱللَّهُ بِضُرٍّ فَلَا كَاشِفَ لَهُۥٓ إِلَّا هُوَ ۖ وَإِن يُرِدْكَ بِخَيْرٍ فَلَا رَآدَّ لِفَضْلِهِۦ ۚ يُصِيبُ بِهِۦ مَن يَشَآءُ مِنْ عِبَادِهِۦ ۚ وَهُوَ ٱلْغَفُورُ ٱلرَّحِيمُ","en":"And if Allāh should touch you with adversity, there is no remover of it except Him; and if He intends for you good, then there is no repeller of His bounty. He causes it to reach whom He wills of His servants. And He is the Forgiving, the Merciful.","tr":"Wa-in yamsaska Allahu bidurrinfala kashifa lahu illa huwa wa-in yuridkabikhayrin fala radda lifadlihi yuseebubihi man yashao min AAibadihi wahuwa alghafooru arraheem","juz":11,"page":221},{"s":10,"a":108,"key":"10:108","ar":"قُلْ يَـٰٓأَيُّهَا ٱلنَّاسُ قَدْ جَآءَكُمُ ٱلْحَقُّ مِن رَّبِّكُمْ ۖ فَمَنِ ٱهْتَدَىٰ فَإِنَّمَا يَهْتَدِى لِنَفْسِهِۦ ۖ وَمَن ضَلَّ فَإِنَّمَا يَضِلُّ عَلَيْهَا ۖ وَمَآ أَنَا۠ عَلَيْكُم بِوَكِيلٍ","en":"Say, \"O mankind, the truth has come to you from your Lord, so whoever is guided is only guided for [the benefit of] his soul, and whoever goes astray only goes astray [in violation] against it. And I am not over you a manager.\"","tr":"Qul ya ayyuha annasuqad jaakumu alhaqqu min rabbikum famani ihtadafa-innama yahtadee linafsihi waman dalla fa-innamayadillu AAalayha wama ana AAalaykumbiwakeel","juz":11,"page":221},{"s":10,"a":109,"key":"10:109","ar":"وَٱتَّبِعْ مَا يُوحَىٰٓ إِلَيْكَ وَٱصْبِرْ حَتَّىٰ يَحْكُمَ ٱللَّهُ ۚ وَهُوَ خَيْرُ ٱلْحَـٰكِمِينَ","en":"And follow what is revealed to you, [O Muḥammad], and be patient until Allāh will judge. And He is the best of judges.","tr":"WattabiAA ma yoohailayka wasbir hatta yahkumaAllahu wahuwa khayru alhakimeen","juz":11,"page":221},{"s":11,"a":1,"key":"11:1","ar":" الٓر ۚ كِتَـٰبٌ أُحْكِمَتْ ءَايَـٰتُهُۥ ثُمَّ فُصِّلَتْ مِن لَّدُنْ حَكِيمٍ خَبِيرٍ","en":"Alif, Lām, Rā.1 [This is] a Book whose verses are perfected and then presented in detail from [one who is] Wise and Aware2","tr":"Alif-lam-ra kitabun ohkimatayatuhu thumma fussilat min ladun hakeeminkhabeer","juz":11,"page":221},{"s":11,"a":2,"key":"11:2","ar":"أَلَّا تَعْبُدُوٓا۟ إِلَّا ٱللَّهَ ۚ إِنَّنِى لَكُم مِّنْهُ نَذِيرٌ وَبَشِيرٌ","en":"[Through a messenger, saying], \"Do not worship except Allāh. Indeed, I am to you from Him a warner and a bringer of good tidings,\"","tr":"Alla taAAbudoo illa Allahainnanee lakum minhu natheerun wabasheer","juz":11,"page":221},{"s":11,"a":3,"key":"11:3","ar":"وَأَنِ ٱسْتَغْفِرُوا۟ رَبَّكُمْ ثُمَّ تُوبُوٓا۟ إِلَيْهِ يُمَتِّعْكُم مَّتَـٰعًا حَسَنًا إِلَىٰٓ أَجَلٍ مُّسَمًّى وَيُؤْتِ كُلَّ ذِى فَضْلٍ فَضْلَهُۥ ۖ وَإِن تَوَلَّوْا۟ فَإِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ كَبِيرٍ","en":"And [saying], \"Seek forgiveness of your Lord and repent to Him, [and] He will let you enjoy a good provision for a specified term and give every doer of favor his favor [i.e., reward]. But if you turn away, then indeed, I fear for you the punishment of a great Day.","tr":"Waani istaghfiroo rabbakum thumma toobooilayhi yumattiAAkum mataAAan hasanan ilaajalin musamman wayu/ti kulla thee fadlin fadlahuwa-in tawallaw fa-inee akhafu AAalaykum AAathabayawmin kabeer","juz":11,"page":221},{"s":11,"a":4,"key":"11:4","ar":"إِلَى ٱللَّهِ مَرْجِعُكُمْ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"To Allāh is your return, and He is over all things competent.\"","tr":"Ila Allahi marjiAAukum wahuwaAAala kulli shay-in qadeer","juz":11,"page":221},{"s":11,"a":5,"key":"11:5","ar":"أَلَآ إِنَّهُمْ يَثْنُونَ صُدُورَهُمْ لِيَسْتَخْفُوا۟ مِنْهُ ۚ أَلَا حِينَ يَسْتَغْشُونَ ثِيَابَهُمْ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ ۚ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"Unquestionably, they [i.e., the disbelievers] turn away their breasts to hide themselves from him. Unquestionably, [even] when they cover themselves in their clothing, He [i.e., Allāh] knows what they conceal and what they declare. Indeed, He is Knowing of that within the breasts.","tr":"Ala innahum yathnoona sudoorahumliyastakhfoo minhu ala heena yastaghshoona thiyabahumyaAAlamu ma yusirroona wama yuAAlinoona innahuAAaleemun bithati assudoor","juz":11,"page":221},{"s":11,"a":6,"key":"11:6","ar":"۞ وَمَا مِن دَآبَّةٍ فِى ٱلْأَرْضِ إِلَّا عَلَى ٱللَّهِ رِزْقُهَا وَيَعْلَمُ مُسْتَقَرَّهَا وَمُسْتَوْدَعَهَا ۚ كُلٌّ فِى كِتَـٰبٍ مُّبِينٍ","en":"And there is no creature on earth but that upon Allāh is its provision, and He knows its place of dwelling and place of storage.1 All is in a clear register.","tr":"Wama min dabbatin fee al-ardiilla AAala Allahi rizquha wayaAAlamumustaqarraha wamustawdaAAaha kullun fee kitabinmubeen","juz":12,"page":222},{"s":11,"a":7,"key":"11:7","ar":"وَهُوَ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ فِى سِتَّةِ أَيَّامٍ وَكَانَ عَرْشُهُۥ عَلَى ٱلْمَآءِ لِيَبْلُوَكُمْ أَيُّكُمْ أَحْسَنُ عَمَلًا ۗ وَلَئِن قُلْتَ إِنَّكُم مَّبْعُوثُونَ مِنۢ بَعْدِ ٱلْمَوْتِ لَيَقُولَنَّ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ هَـٰذَآ إِلَّا سِحْرٌ مُّبِينٌ","en":"And it is He who created the heavens and the earth in six days - and His Throne had been upon water - that He might test you as to which of you is best in deed. But if you say, \"Indeed, you are resurrected after death,\" those who disbelieve will surely say, \"This is not but obvious magic.\"","tr":"Wahuwa allathee khalaqa assamawatiwal-arda fee sittati ayyamin wakanaAAarshuhu AAala alma-i liyabluwakum ayyukum ahsanuAAamalan wala-in qulta innakum mabAAoothoona min baAAdi almawtilayaqoolanna allatheena kafaroo in hatha illasihrun mubeen","juz":12,"page":222},{"s":11,"a":8,"key":"11:8","ar":"وَلَئِنْ أَخَّرْنَا عَنْهُمُ ٱلْعَذَابَ إِلَىٰٓ أُمَّةٍ مَّعْدُودَةٍ لَّيَقُولُنَّ مَا يَحْبِسُهُۥٓ ۗ أَلَا يَوْمَ يَأْتِيهِمْ لَيْسَ مَصْرُوفًا عَنْهُمْ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"And if We hold back from them the punishment for a limited time, they will surely say,1 \"What detains it?\" Unquestionably, on the Day it comes to them, it will not be averted from them, and they will be enveloped by what they used to ridicule.","tr":"Wala-in akhkharna AAanhumu alAAathabaila ommatin maAAdoodatin layaqoolunna ma yahbisuhuala yawma ya/teehim laysa masroofan AAanhum wahaqabihim ma kanoo bihi yastahzi-oon","juz":12,"page":222},{"s":11,"a":9,"key":"11:9","ar":"وَلَئِنْ أَذَقْنَا ٱلْإِنسَـٰنَ مِنَّا رَحْمَةً ثُمَّ نَزَعْنَـٰهَا مِنْهُ إِنَّهُۥ لَيَـُٔوسٌ كَفُورٌ","en":"And if We give man a taste of mercy from Us and then We withdraw it from him, indeed, he is despairing and ungrateful.","tr":"Wala-in athaqna al-insanaminna rahmatan thumma nazaAAnahaminhu innahu layaoosun kafoor","juz":12,"page":222},{"s":11,"a":10,"key":"11:10","ar":"وَلَئِنْ أَذَقْنَـٰهُ نَعْمَآءَ بَعْدَ ضَرَّآءَ مَسَّتْهُ لَيَقُولَنَّ ذَهَبَ ٱلسَّيِّـَٔاتُ عَنِّىٓ ۚ إِنَّهُۥ لَفَرِحٌ فَخُورٌ","en":"But if We give him a taste of favor after hardship has touched him, he will surely say, \"Bad times have left me.\" Indeed, he is exultant and boastful -","tr":"Wala-in athaqnahu naAAmaabaAAda darraa massat-hu layaqoolanna thahabaassayyi-atu AAannee innahu lafarihunfakhoor","juz":12,"page":222},{"s":11,"a":11,"key":"11:11","ar":"إِلَّا ٱلَّذِينَ صَبَرُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ أُو۟لَـٰٓئِكَ لَهُم مَّغْفِرَةٌ وَأَجْرٌ كَبِيرٌ","en":"Except for those who are patient and do righteous deeds; those will have forgiveness and great reward.","tr":"Illa allatheena sabaroowaAAamiloo assalihati ola-ika lahummaghfiratun waajrun kabeer","juz":12,"page":222},{"s":11,"a":12,"key":"11:12","ar":"فَلَعَلَّكَ تَارِكٌۢ بَعْضَ مَا يُوحَىٰٓ إِلَيْكَ وَضَآئِقٌۢ بِهِۦ صَدْرُكَ أَن يَقُولُوا۟ لَوْلَآ أُنزِلَ عَلَيْهِ كَنزٌ أَوْ جَآءَ مَعَهُۥ مَلَكٌ ۚ إِنَّمَآ أَنتَ نَذِيرٌ ۚ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ وَكِيلٌ","en":"Then would you possibly leave [out] some of what is revealed to you,1 or is your breast constrained by it because they say, \"Why has there not been sent down to him a treasure or come with him an angel?\" But you are only a warner. And Allāh is Disposer of all things.","tr":"FalaAAallaka tarikun baAAda mayooha ilayka wada-iqun bihi sadruka anyaqooloo lawla onzila AAalayhi kanzun aw jaamaAAahu malakun innama anta natheerun wallahuAAala kulli shay-in wakeel","juz":12,"page":222},{"s":11,"a":13,"key":"11:13","ar":"أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۖ قُلْ فَأْتُوا۟ بِعَشْرِ سُوَرٍ مِّثْلِهِۦ مُفْتَرَيَـٰتٍ وَٱدْعُوا۟ مَنِ ٱسْتَطَعْتُم مِّن دُونِ ٱللَّهِ إِن كُنتُمْ صَـٰدِقِينَ","en":"Or do they say, \"He invented it\"? Say, \"Then bring ten sūrahs like it that have been invented and call upon [for assistance] whomever you can besides Allāh, if you should be truthful.\"","tr":"Am yaqooloona iftarahu qul fa/toobiAAashri suwarin mithlihi muftarayatin wadAAoomani istataAAtum min dooni Allahi in kuntum sadiqeen","juz":12,"page":223},{"s":11,"a":14,"key":"11:14","ar":"فَإِلَّمْ يَسْتَجِيبُوا۟ لَكُمْ فَٱعْلَمُوٓا۟ أَنَّمَآ أُنزِلَ بِعِلْمِ ٱللَّهِ وَأَن لَّآ إِلَـٰهَ إِلَّا هُوَ ۖ فَهَلْ أَنتُم مُّسْلِمُونَ","en":"And if they do not respond to you - then know that it [i.e., the Qur’ān] was revealed with the knowledge of Allāh1 and that there is no deity except Him. Then,2 would you [not] be Muslims?","tr":"Fa-illam yastajeeboo lakum faAAlamooannama onzila biAAilmi Allahi waan la ilahailla huwa fahal antum muslimoon","juz":12,"page":223},{"s":11,"a":15,"key":"11:15","ar":"مَن كَانَ يُرِيدُ ٱلْحَيَوٰةَ ٱلدُّنْيَا وَزِينَتَهَا نُوَفِّ إِلَيْهِمْ أَعْمَـٰلَهُمْ فِيهَا وَهُمْ فِيهَا لَا يُبْخَسُونَ","en":"Whoever desires the life of this world and its adornments - We fully repay them for their deeds therein,1 and they therein will not be deprived.","tr":"Man kana yureedu alhayataaddunya wazeenataha nuwaffi ilayhim aAAmalahumfeeha wahum feeha la yubkhasoon","juz":12,"page":223},{"s":11,"a":16,"key":"11:16","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ لَيْسَ لَهُمْ فِى ٱلْـَٔاخِرَةِ إِلَّا ٱلنَّارُ ۖ وَحَبِطَ مَا صَنَعُوا۟ فِيهَا وَبَـٰطِلٌ مَّا كَانُوا۟ يَعْمَلُونَ","en":"Those are the ones for whom there is not in the Hereafter but the Fire. And lost is what they did therein,1 and worthless is what they used to do.","tr":"Ola-ika allatheena laysa lahumfee al-akhirati illa annaru wahabitama sanaAAoo feeha wabatilun makanoo yaAAmaloon","juz":12,"page":223},{"s":11,"a":17,"key":"11:17","ar":"أَفَمَن كَانَ عَلَىٰ بَيِّنَةٍ مِّن رَّبِّهِۦ وَيَتْلُوهُ شَاهِدٌ مِّنْهُ وَمِن قَبْلِهِۦ كِتَـٰبُ مُوسَىٰٓ إِمَامًا وَرَحْمَةً ۚ أُو۟لَـٰٓئِكَ يُؤْمِنُونَ بِهِۦ ۚ وَمَن يَكْفُرْ بِهِۦ مِنَ ٱلْأَحْزَابِ فَٱلنَّارُ مَوْعِدُهُۥ ۚ فَلَا تَكُ فِى مِرْيَةٍ مِّنْهُ ۚ إِنَّهُ ٱلْحَقُّ مِن رَّبِّكَ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يُؤْمِنُونَ","en":"So is one who [stands] upon a clear evidence from his Lord [like the aforementioned]? And a witness1 from Him follows it,2 and before it was the Scripture of Moses to lead and as mercy. Those [believers in the former revelations] believe in it [i.e., the Qur’ān]. But whoever disbelieves in it from the [various] factions - the Fire is his promised destination. So be not in doubt about it. Indeed, it is the truth from your Lord, but most of the people do not believe.","tr":"Afaman kana AAala bayyinatinmin rabbihi wayatloohu shahidun minhu wamin qablihi kitabumoosa imaman warahmatan ola-ikayu/minoona bihi waman yakfur bihi mina al-ahzabi fannarumawAAiduhu fala taku fee miryatin minhu innahu alhaqqumin rabbika walakinna akthara annasi layu/minoon","juz":12,"page":223},{"s":11,"a":18,"key":"11:18","ar":"وَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا ۚ أُو۟لَـٰٓئِكَ يُعْرَضُونَ عَلَىٰ رَبِّهِمْ وَيَقُولُ ٱلْأَشْهَـٰدُ هَـٰٓؤُلَآءِ ٱلَّذِينَ كَذَبُوا۟ عَلَىٰ رَبِّهِمْ ۚ أَلَا لَعْنَةُ ٱللَّهِ عَلَى ٱلظَّـٰلِمِينَ","en":"And who is more unjust than he who invents a lie about Allāh? Those will be presented before their Lord, and the witnesses will say, \"These are the ones who lied against their Lord.\" Unquestionably, the curse of Allāh is upon the wrongdoers.","tr":"Waman athlamu mimmani iftaraAAala Allahi kathiban ola-ika yuAAradoonaAAala rabbihim wayaqoolu al-ashhadu haola-iallatheena kathaboo AAala rabbihim alalaAAnatu Allahi AAala aththalimeen","juz":12,"page":223},{"s":11,"a":19,"key":"11:19","ar":"ٱلَّذِينَ يَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَيَبْغُونَهَا عِوَجًا وَهُم بِٱلْـَٔاخِرَةِ هُمْ كَـٰفِرُونَ","en":"Who averted [people] from the way of Allāh and sought to make it [seem] deviant while they, concerning the Hereafter, were disbelievers.","tr":"Allatheena yasuddoona AAansabeeli Allahi wayabghoonaha AAiwajan wahum bil-akhiratihum kafiroon","juz":12,"page":223},{"s":11,"a":20,"key":"11:20","ar":"أُو۟لَـٰٓئِكَ لَمْ يَكُونُوا۟ مُعْجِزِينَ فِى ٱلْأَرْضِ وَمَا كَانَ لَهُم مِّن دُونِ ٱللَّهِ مِنْ أَوْلِيَآءَ ۘ يُضَـٰعَفُ لَهُمُ ٱلْعَذَابُ ۚ مَا كَانُوا۟ يَسْتَطِيعُونَ ٱلسَّمْعَ وَمَا كَانُوا۟ يُبْصِرُونَ","en":"Those were not causing failure [to Allāh] on earth, nor did they have besides Allāh any protectors. For them the punishment will be multiplied. They were not able to hear, nor did they see.1","tr":"Ola-ika lam yakoonoo muAAjizeena feeal-ardi wama kana lahum min dooni Allahimin awliyaa yudaAAafu lahumu alAAathabu makanoo yastateeAAoona assamAAa wama kanooyubsiroon","juz":12,"page":224},{"s":11,"a":21,"key":"11:21","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ","en":"Those are the ones who will have lost themselves, and lost from them is what they used to invent.","tr":"Ola-ika allatheena khasirooanfusahum wadalla AAanhum ma kanoo yaftaroon","juz":12,"page":224},{"s":11,"a":22,"key":"11:22","ar":"لَا جَرَمَ أَنَّهُمْ فِى ٱلْـَٔاخِرَةِ هُمُ ٱلْأَخْسَرُونَ","en":"Assuredly, it is they in the Hereafter who will be the greatest losers.","tr":"La jarama annahum fee al-akhiratihumu al-akhsaroon","juz":12,"page":224},{"s":11,"a":23,"key":"11:23","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ وَأَخْبَتُوٓا۟ إِلَىٰ رَبِّهِمْ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْجَنَّةِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"Indeed, they who have believed and done righteous deeds and humbled themselves to their Lord - those are the companions of Paradise; they will abide eternally therein.","tr":"Inna allatheena amanoowaAAamiloo asalihati waakhbatoo ilarabbihim ola-ika as-habu aljannati hum feehakhalidoon","juz":12,"page":224},{"s":11,"a":24,"key":"11:24","ar":"۞ مَثَلُ ٱلْفَرِيقَيْنِ كَٱلْأَعْمَىٰ وَٱلْأَصَمِّ وَٱلْبَصِيرِ وَٱلسَّمِيعِ ۚ هَلْ يَسْتَوِيَانِ مَثَلًا ۚ أَفَلَا تَذَكَّرُونَ","en":"The example of the two parties is like the blind and deaf, and the seeing and hearing. Are they equal in comparison? Then, will you not remember?","tr":"Mathalu alfareeqayni kalaAAmawal-asammi walbaseeri wassameeAAihal yastawiyani mathalan afala tathakkaroon","juz":12,"page":224},{"s":11,"a":25,"key":"11:25","ar":"وَلَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦٓ إِنِّى لَكُمْ نَذِيرٌ مُّبِينٌ","en":"And We had certainly sent Noah to his people, [saying], \"Indeed, I am to you a clear warner","tr":"Walaqad arsalna noohan ilaqawmihi innee lakum natheerun mubeen","juz":12,"page":224},{"s":11,"a":26,"key":"11:26","ar":"أَن لَّا تَعْبُدُوٓا۟ إِلَّا ٱللَّهَ ۖ إِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ أَلِيمٍ","en":"That you not worship except Allāh. Indeed, I fear for you the punishment of a painful day.\"","tr":"An la taAAbudoo illa Allahainnee akhafu AAalaykum AAathaba yawmin aleem","juz":12,"page":224},{"s":11,"a":27,"key":"11:27","ar":"فَقَالَ ٱلْمَلَأُ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦ مَا نَرَىٰكَ إِلَّا بَشَرًا مِّثْلَنَا وَمَا نَرَىٰكَ ٱتَّبَعَكَ إِلَّا ٱلَّذِينَ هُمْ أَرَاذِلُنَا بَادِىَ ٱلرَّأْىِ وَمَا نَرَىٰ لَكُمْ عَلَيْنَا مِن فَضْلٍۭ بَلْ نَظُنُّكُمْ كَـٰذِبِينَ","en":"So the eminent among those who disbelieved from his people said, \"We do not see you but as a man like ourselves, and we do not see you followed except by those who are the lowest of us [and] at first suggestion.1 And we do not see in you over us any merit; rather, we think you are liars.\"","tr":"Faqala almalao allatheenakafaroo min qawmihi ma naraka illa basharanmithlana wama naraka ittabaAAaka illaallatheena hum arathiluna badiya arra/yiwama nara lakum AAalayna min fadlinbal nathunnukum kathibeen","juz":12,"page":224},{"s":11,"a":28,"key":"11:28","ar":"قَالَ يَـٰقَوْمِ أَرَءَيْتُمْ إِن كُنتُ عَلَىٰ بَيِّنَةٍ مِّن رَّبِّى وَءَاتَىٰنِى رَحْمَةً مِّنْ عِندِهِۦ فَعُمِّيَتْ عَلَيْكُمْ أَنُلْزِمُكُمُوهَا وَأَنتُمْ لَهَا كَـٰرِهُونَ","en":"He said, \"O my people, have you considered: if I should be upon clear evidence from my Lord while He has given me mercy from Himself but it has been made unapparent to you, should we force it upon you while you are averse to it?","tr":"Qala ya qawmi araaytum inkuntu AAala bayyinatin min rabbee waataneerahmatan min AAindihi faAAummiyat AAalaykum anulzimukumoohawaantum laha karihoon","juz":12,"page":224},{"s":11,"a":29,"key":"11:29","ar":"وَيَـٰقَوْمِ لَآ أَسْـَٔلُكُمْ عَلَيْهِ مَالًا ۖ إِنْ أَجْرِىَ إِلَّا عَلَى ٱللَّهِ ۚ وَمَآ أَنَا۠ بِطَارِدِ ٱلَّذِينَ ءَامَنُوٓا۟ ۚ إِنَّهُم مُّلَـٰقُوا۟ رَبِّهِمْ وَلَـٰكِنِّىٓ أَرَىٰكُمْ قَوْمًا تَجْهَلُونَ","en":"And O my people, I ask not of you for it any wealth. My reward is not but from Allāh. And I am not one to drive away those who have believed. Indeed, they will meet their Lord, but I see that you are a people behaving ignorantly.","tr":"Waya qawmi la as-alukumAAalayhi malan in ajriya illa AAala Allahiwama ana bitaridi allatheena amanooinnahum mulaqoo rabbihim walakinnee arakumqawman tajhaloon","juz":12,"page":225},{"s":11,"a":30,"key":"11:30","ar":"وَيَـٰقَوْمِ مَن يَنصُرُنِى مِنَ ٱللَّهِ إِن طَرَدتُّهُمْ ۚ أَفَلَا تَذَكَّرُونَ","en":"And O my people, who would protect me from Allāh if I drove them away? Then will you not be reminded?","tr":"Waya qawmi man yansurunee minaAllahi in taradtuhum afala tathakkaroon","juz":12,"page":225},{"s":11,"a":31,"key":"11:31","ar":"وَلَآ أَقُولُ لَكُمْ عِندِى خَزَآئِنُ ٱللَّهِ وَلَآ أَعْلَمُ ٱلْغَيْبَ وَلَآ أَقُولُ إِنِّى مَلَكٌ وَلَآ أَقُولُ لِلَّذِينَ تَزْدَرِىٓ أَعْيُنُكُمْ لَن يُؤْتِيَهُمُ ٱللَّهُ خَيْرًا ۖ ٱللَّهُ أَعْلَمُ بِمَا فِىٓ أَنفُسِهِمْ ۖ إِنِّىٓ إِذًا لَّمِنَ ٱلظَّـٰلِمِينَ","en":"And I do not tell you that I have the depositories [containing the provision] of Allāh or that I know the unseen, nor do I tell you that I am an angel, nor do I say of those upon whom your eyes look down that Allāh will never grant them any good. Allāh is most knowing of what is within their souls. Indeed, I would then be among the wrongdoers [i.e., the unjust].\"","tr":"Wala aqoolu lakum AAindee khaza-inuAllahi wala aAAlamu alghayba wala aqooluinnee malakun wala aqoolu lillatheena tazdareeaAAyunukum lan yu/tiyahumu Allahu khayran AllahuaAAlamu bima fee anfusihim innee ithan lamina aththalimeen","juz":12,"page":225},{"s":11,"a":32,"key":"11:32","ar":"قَالُوا۟ يَـٰنُوحُ قَدْ جَـٰدَلْتَنَا فَأَكْثَرْتَ جِدَٰلَنَا فَأْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ","en":"They said, \"O Noah, you have disputed [i.e., opposed] us and been frequent in dispute of us. So bring us what you threaten us, if you should be of the truthful.\"","tr":"Qaloo ya noohu qad jadaltanafaaktharta jidalana fa/tina bimataAAiduna in kunta mina assadiqeen","juz":12,"page":225},{"s":11,"a":33,"key":"11:33","ar":"قَالَ إِنَّمَا يَأْتِيكُم بِهِ ٱللَّهُ إِن شَآءَ وَمَآ أَنتُم بِمُعْجِزِينَ","en":"He said, \"Allāh will only bring it to you if He wills, and you will not cause [Him] failure.","tr":"Qala innama ya/teekum bihi Allahuin shaa wama antum bimuAAjizeen","juz":12,"page":225},{"s":11,"a":34,"key":"11:34","ar":"وَلَا يَنفَعُكُمْ نُصْحِىٓ إِنْ أَرَدتُّ أَنْ أَنصَحَ لَكُمْ إِن كَانَ ٱللَّهُ يُرِيدُ أَن يُغْوِيَكُمْ ۚ هُوَ رَبُّكُمْ وَإِلَيْهِ تُرْجَعُونَ","en":"And my advice will not benefit you - although I wished to advise you - if Allāh should intend to put you in error. He is your Lord, and to Him you will be returned.\"","tr":"Wala yanfaAAukum nushee inaradtu an ansaha lakum in kana Allahuyureedu an yughwiyakum huwa rabbukum wa-ilayhi turjaAAoon","juz":12,"page":225},{"s":11,"a":35,"key":"11:35","ar":"أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۖ قُلْ إِنِ ٱفْتَرَيْتُهُۥ فَعَلَىَّ إِجْرَامِى وَأَنَا۠ بَرِىٓءٌ مِّمَّا تُجْرِمُونَ","en":"Or do they say [about Prophet Muḥammad (ﷺ)], \"He invented it\"? Say, \"If I have invented it, then upon me is [the consequence of] my crime; but I am innocent of what [crimes] you commit.\"","tr":"Am yaqooloona iftarahu qul iniiftaraytuhu faAAalayya ijramee waana baree-on mimmatujrimoon","juz":12,"page":225},{"s":11,"a":36,"key":"11:36","ar":"وَأُوحِىَ إِلَىٰ نُوحٍ أَنَّهُۥ لَن يُؤْمِنَ مِن قَوْمِكَ إِلَّا مَن قَدْ ءَامَنَ فَلَا تَبْتَئِسْ بِمَا كَانُوا۟ يَفْعَلُونَ","en":"And it was revealed to Noah that, \"No one will believe from your people except those who have already believed, so do not be distressed by what they have been doing.","tr":"Waoohiya ila noohinannahu lan yu/mina min qawmika illa man qad amanafala tabta-is bima kanoo yafAAaloon","juz":12,"page":225},{"s":11,"a":37,"key":"11:37","ar":"وَٱصْنَعِ ٱلْفُلْكَ بِأَعْيُنِنَا وَوَحْيِنَا وَلَا تُخَـٰطِبْنِى فِى ٱلَّذِينَ ظَلَمُوٓا۟ ۚ إِنَّهُم مُّغْرَقُونَ","en":"And construct the ship under Our observation and Our inspiration and do not address Me concerning those who have wronged; indeed, they are [to be] drowned.\"","tr":"WasnaAAi alfulka bi-aAAyuninawawahyina wala tukhatibnee fee allatheenathalamoo innahum mughraqoon","juz":12,"page":225},{"s":11,"a":38,"key":"11:38","ar":"وَيَصْنَعُ ٱلْفُلْكَ وَكُلَّمَا مَرَّ عَلَيْهِ مَلَأٌ مِّن قَوْمِهِۦ سَخِرُوا۟ مِنْهُ ۚ قَالَ إِن تَسْخَرُوا۟ مِنَّا فَإِنَّا نَسْخَرُ مِنكُمْ كَمَا تَسْخَرُونَ","en":"And he constructed the ship, and whenever an assembly of the eminent of his people passed by him, they ridiculed him. He said, \"If you ridicule us, then we will ridicule you just as you ridicule.","tr":"WayasnaAAu alfulka wakullamamarra AAalayhi malaon min qawmihi sakhiroo minhu qala intaskharoo minna fa-inna naskharu minkum kamataskharoon","juz":12,"page":226},{"s":11,"a":39,"key":"11:39","ar":"فَسَوْفَ تَعْلَمُونَ مَن يَأْتِيهِ عَذَابٌ يُخْزِيهِ وَيَحِلُّ عَلَيْهِ عَذَابٌ مُّقِيمٌ","en":"And you are going to know who will get a punishment that will disgrace him [on earth] and upon whom will descend an enduring punishment [in the Hereafter].\"","tr":"Fasawfa taAAlamoona man ya/teehi AAathabunyukhzeehi wayahillu AAalayhi AAathabun muqeem","juz":12,"page":226},{"s":11,"a":40,"key":"11:40","ar":"حَتَّىٰٓ إِذَا جَآءَ أَمْرُنَا وَفَارَ ٱلتَّنُّورُ قُلْنَا ٱحْمِلْ فِيهَا مِن كُلٍّ زَوْجَيْنِ ٱثْنَيْنِ وَأَهْلَكَ إِلَّا مَن سَبَقَ عَلَيْهِ ٱلْقَوْلُ وَمَنْ ءَامَنَ ۚ وَمَآ ءَامَنَ مَعَهُۥٓ إِلَّا قَلِيلٌ","en":"[So it was], until when Our command came and the oven overflowed,1 We said, \"Load upon it [i.e., the ship] of each [creature] two mates and your family, except those about whom the word [i.e., decree] has preceded, and [include] whoever has believed.\" But none had believed with him, except a few.","tr":"Hatta itha jaaamruna wafara attannooru qulna ihmilfeeha min kullin zawjayni ithnayni waahlaka illaman sabaqa AAalayhi alqawlu waman amana wama amanamaAAahu illa qaleel","juz":12,"page":226},{"s":11,"a":41,"key":"11:41","ar":"۞ وَقَالَ ٱرْكَبُوا۟ فِيهَا بِسْمِ ٱللَّهِ مَجْر۪ىٰهَا وَمُرْسَىٰهَآ ۚ إِنَّ رَبِّى لَغَفُورٌ رَّحِيمٌ","en":"And [Noah] said, \"Embark therein; in the name of Allāh [are] its course and its anchorage. Indeed, my Lord is Forgiving and Merciful.\"","tr":"Waqala irkaboo feeha bismi Allahimajraha wamursaha inna rabbeelaghafoorun raheem","juz":12,"page":226},{"s":11,"a":42,"key":"11:42","ar":"وَهِىَ تَجْرِى بِهِمْ فِى مَوْجٍ كَٱلْجِبَالِ وَنَادَىٰ نُوحٌ ٱبْنَهُۥ وَكَانَ فِى مَعْزِلٍ يَـٰبُنَىَّ ٱرْكَب مَّعَنَا وَلَا تَكُن مَّعَ ٱلْكَـٰفِرِينَ","en":"And it sailed with them through waves like mountains, and Noah called to his son who was apart [from them], \"O my son, come aboard with us and be not with the disbelievers.\"","tr":"Wahiya tajree bihim fee mawjin kaljibaliwanada noohunu ibnahu wakana feemaAAzilin ya bunayya irkab maAAana walatakun maAAa alkafireen","juz":12,"page":226},{"s":11,"a":43,"key":"11:43","ar":"قَالَ سَـَٔاوِىٓ إِلَىٰ جَبَلٍ يَعْصِمُنِى مِنَ ٱلْمَآءِ ۚ قَالَ لَا عَاصِمَ ٱلْيَوْمَ مِنْ أَمْرِ ٱللَّهِ إِلَّا مَن رَّحِمَ ۚ وَحَالَ بَيْنَهُمَا ٱلْمَوْجُ فَكَانَ مِنَ ٱلْمُغْرَقِينَ","en":"[But] he said, \"I will take refuge on a mountain to protect me from the water.\" [Noah] said, \"There is no protector today from the decree of Allāh, except for whom He gives mercy.\" And the waves came between them, and he was among the drowned.","tr":"Qala saawee ila jabalinyaAAsimunee mina alma-i qala la AAasimaalyawma min amri Allahi illa man rahima wahalabaynahuma almawju fakana mina almughraqeen","juz":12,"page":226},{"s":11,"a":44,"key":"11:44","ar":"وَقِيلَ يَـٰٓأَرْضُ ٱبْلَعِى مَآءَكِ وَيَـٰسَمَآءُ أَقْلِعِى وَغِيضَ ٱلْمَآءُ وَقُضِىَ ٱلْأَمْرُ وَٱسْتَوَتْ عَلَى ٱلْجُودِىِّ ۖ وَقِيلَ بُعْدًا لِّلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"And it was said, \"O earth, swallow your water, and O sky, withhold [your rain].\" And the water subsided, and the matter was accomplished, and it [i.e., the ship] came to rest on the [mountain of] Jūdiyy. And it was said, \"Away with the wrongdoing people.\"","tr":"Waqeela ya ardu iblaAAee maakiwaya samao aqliAAee wagheeda almaowaqudiya al-amru wastawat AAala aljoodiyyiwaqeela buAAdan lilqawmi aththalimeen","juz":12,"page":226},{"s":11,"a":45,"key":"11:45","ar":"وَنَادَىٰ نُوحٌ رَّبَّهُۥ فَقَالَ رَبِّ إِنَّ ٱبْنِى مِنْ أَهْلِى وَإِنَّ وَعْدَكَ ٱلْحَقُّ وَأَنتَ أَحْكَمُ ٱلْحَـٰكِمِينَ","en":"And Noah called to his Lord and said, \"My Lord, indeed my son is of my family; and indeed, Your promise is true; and You are the most just of judges!\"","tr":"Wanada noohun rabbahufaqala rabbi inna ibnee min ahlee wa-inna waAAdaka alhaqquwaanta ahkamu alhakimeen","juz":12,"page":226},{"s":11,"a":46,"key":"11:46","ar":"قَالَ يَـٰنُوحُ إِنَّهُۥ لَيْسَ مِنْ أَهْلِكَ ۖ إِنَّهُۥ عَمَلٌ غَيْرُ صَـٰلِحٍ ۖ فَلَا تَسْـَٔلْنِ مَا لَيْسَ لَكَ بِهِۦ عِلْمٌ ۖ إِنِّىٓ أَعِظُكَ أَن تَكُونَ مِنَ ٱلْجَـٰهِلِينَ","en":"He said, \"O Noah, indeed he is not of your family; indeed, he is [one whose] work was other than righteous, so ask Me not for that about which you have no knowledge. Indeed, I advise you, lest you be among the ignorant.\"","tr":"Qala ya noohu innahulaysa min ahlika innahu AAamalun ghayru salihin falatas-alni ma laysa laka bihi AAilmun innee aAAithukaan takoona mina aljahileen","juz":12,"page":227},{"s":11,"a":47,"key":"11:47","ar":"قَالَ رَبِّ إِنِّىٓ أَعُوذُ بِكَ أَنْ أَسْـَٔلَكَ مَا لَيْسَ لِى بِهِۦ عِلْمٌ ۖ وَإِلَّا تَغْفِرْ لِى وَتَرْحَمْنِىٓ أَكُن مِّنَ ٱلْخَـٰسِرِينَ","en":"[Noah] said, \"My Lord, I seek refuge in You from asking that of which I have no knowledge. And unless You forgive me and have mercy upon me, I will be among the losers.\"","tr":"Qala rabbi innee aAAoothu bikaan as-alaka ma laysa lee bihi AAilmun wa-illataghfir lee watarhamnee akun mina alkhasireen","juz":12,"page":227},{"s":11,"a":48,"key":"11:48","ar":"قِيلَ يَـٰنُوحُ ٱهْبِطْ بِسَلَـٰمٍ مِّنَّا وَبَرَكَـٰتٍ عَلَيْكَ وَعَلَىٰٓ أُمَمٍ مِّمَّن مَّعَكَ ۚ وَأُمَمٌ سَنُمَتِّعُهُمْ ثُمَّ يَمَسُّهُم مِّنَّا عَذَابٌ أَلِيمٌ","en":"It was said, \"O Noah, disembark in security from Us and blessings upon you and upon nations [descending] from those with you. But other nations [of them] We will grant enjoyment; then there will touch them from Us a painful punishment.\"","tr":"Qeela ya noohu ihbitbisalamin minna wabarakatin AAalayka waAAalaomamin mimman maAAaka waomamun sanumattiAAuhum thumma yamassuhumminna AAathabun aleem","juz":12,"page":227},{"s":11,"a":49,"key":"11:49","ar":"تِلْكَ مِنْ أَنۢبَآءِ ٱلْغَيْبِ نُوحِيهَآ إِلَيْكَ ۖ مَا كُنتَ تَعْلَمُهَآ أَنتَ وَلَا قَوْمُكَ مِن قَبْلِ هَـٰذَا ۖ فَٱصْبِرْ ۖ إِنَّ ٱلْعَـٰقِبَةَ لِلْمُتَّقِينَ","en":"That is from the news of the unseen which We reveal to you, [O Muḥammad]. You knew it not, neither you nor your people, before this. So be patient; indeed, the [best] outcome is for the righteous.","tr":"Tilka min anba-i alghaybi nooheehailayka ma kunta taAAlamuha anta wala qawmukamin qabli hatha fasbir inna alAAaqibatalilmuttaqeen","juz":12,"page":227},{"s":11,"a":50,"key":"11:50","ar":"وَإِلَىٰ عَادٍ أَخَاهُمْ هُودًا ۚ قَالَ يَـٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَـٰهٍ غَيْرُهُۥٓ ۖ إِنْ أَنتُمْ إِلَّا مُفْتَرُونَ","en":"And to ʿAad [We sent] their brother Hūd. He said, \"O my people, worship Allāh; you have no deity other than Him. You are not but inventors [of falsehood].","tr":"Wa-ila AAadin akhahumhoodan qala ya qawmi oAAbudoo Allaha malakum min ilahin ghayruhu in antum illa muftaroon","juz":12,"page":227},{"s":11,"a":51,"key":"11:51","ar":"يَـٰقَوْمِ لَآ أَسْـَٔلُكُمْ عَلَيْهِ أَجْرًا ۖ إِنْ أَجْرِىَ إِلَّا عَلَى ٱلَّذِى فَطَرَنِىٓ ۚ أَفَلَا تَعْقِلُونَ","en":"O my people, I do not ask you for it [i.e., my advice] any reward. My reward is only from the one who created me. Then will you not reason?","tr":"Ya qawmi la as-alukum AAalayhiajran in ajriya illa AAala allathee fataraneeafala taAAqiloon","juz":12,"page":227},{"s":11,"a":52,"key":"11:52","ar":"وَيَـٰقَوْمِ ٱسْتَغْفِرُوا۟ رَبَّكُمْ ثُمَّ تُوبُوٓا۟ إِلَيْهِ يُرْسِلِ ٱلسَّمَآءَ عَلَيْكُم مِّدْرَارًا وَيَزِدْكُمْ قُوَّةً إِلَىٰ قُوَّتِكُمْ وَلَا تَتَوَلَّوْا۟ مُجْرِمِينَ","en":"And O my people, ask forgiveness of your Lord and then repent to Him. He will send [rain from] the sky upon you in showers and increase you in strength [added] to your strength. And do not turn away, [being] criminals.\"","tr":"Waya qawmi istaghfiroo rabbakumthumma tooboo ilayhi yursili assamaa AAalaykummidraran wayazidkum quwwatan ila quwwatikum walatatawallaw mujrimeen","juz":12,"page":227},{"s":11,"a":53,"key":"11:53","ar":"قَالُوا۟ يَـٰهُودُ مَا جِئْتَنَا بِبَيِّنَةٍ وَمَا نَحْنُ بِتَارِكِىٓ ءَالِهَتِنَا عَن قَوْلِكَ وَمَا نَحْنُ لَكَ بِمُؤْمِنِينَ","en":"They said, \"O Hūd, you have not brought us clear evidence, and we are not ones to leave our gods on your say-so. Nor are we believers in you.","tr":"Qaloo ya hoodu maji/tana bibayyinatin wama nahnu bitarikeealihatina AAan qawlika wama nahnulaka bimu/mineen","juz":12,"page":227},{"s":11,"a":54,"key":"11:54","ar":"إِن نَّقُولُ إِلَّا ٱعْتَرَىٰكَ بَعْضُ ءَالِهَتِنَا بِسُوٓءٍ ۗ قَالَ إِنِّىٓ أُشْهِدُ ٱللَّهَ وَٱشْهَدُوٓا۟ أَنِّى بَرِىٓءٌ مِّمَّا تُشْرِكُونَ","en":"We only say that some of our gods have possessed you with evil [i.e., insanity].\" He said, \"Indeed, I call Allāh to witness, and witness [yourselves] that I am free from whatever you associate with Allāh","tr":"In naqoolu illa iAAtaraka baAAdualihatina bisoo-in qala innee oshhidu Allahawashhadoo annee baree-on mimma tushrikoon","juz":12,"page":228},{"s":11,"a":55,"key":"11:55","ar":"مِن دُونِهِۦ ۖ فَكِيدُونِى جَمِيعًا ثُمَّ لَا تُنظِرُونِ","en":"Other than Him. So plot against me all together; then do not give me respite.","tr":"Min doonihi fakeedoonee jameeAAan thumma latunthiroon","juz":12,"page":228},{"s":11,"a":56,"key":"11:56","ar":"إِنِّى تَوَكَّلْتُ عَلَى ٱللَّهِ رَبِّى وَرَبِّكُم ۚ مَّا مِن دَآبَّةٍ إِلَّا هُوَ ءَاخِذٌۢ بِنَاصِيَتِهَآ ۚ إِنَّ رَبِّى عَلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"Indeed, I have relied upon Allāh, my Lord and your Lord. There is no creature but that He holds it by its forelock [i.e., controls it]. Indeed, my Lord is on a path [that is] straight.","tr":"Innee tawakkaltu AAala Allahirabbee warabbikum ma min dabbatin illa huwa akhithunbinasiyatiha inna rabbee AAala siratinmustaqeem","juz":12,"page":228},{"s":11,"a":57,"key":"11:57","ar":"فَإِن تَوَلَّوْا۟ فَقَدْ أَبْلَغْتُكُم مَّآ أُرْسِلْتُ بِهِۦٓ إِلَيْكُمْ ۚ وَيَسْتَخْلِفُ رَبِّى قَوْمًا غَيْرَكُمْ وَلَا تَضُرُّونَهُۥ شَيْـًٔا ۚ إِنَّ رَبِّى عَلَىٰ كُلِّ شَىْءٍ حَفِيظٌ","en":"But if you turn away, then I have already conveyed that with which I was sent to you. My Lord will give succession to a people other than you, and you will not harm Him at all. Indeed my Lord is, over all things, Guardian.\"1","tr":"Fa-in tawallaw faqad ablaghtukum maorsiltu bihi ilaykum wayastakhlifu rabbee qawman ghayrakum walatadurroonahu shay-an inna rabbee AAala kullishay-in hafeeth","juz":12,"page":228},{"s":11,"a":58,"key":"11:58","ar":"وَلَمَّا جَآءَ أَمْرُنَا نَجَّيْنَا هُودًا وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ بِرَحْمَةٍ مِّنَّا وَنَجَّيْنَـٰهُم مِّنْ عَذَابٍ غَلِيظٍ","en":"And when Our command came, We saved Hūd and those who believed with him, by mercy from Us; and We saved them from a harsh punishment.","tr":"Walamma jaa amrunanajjayna hoodan wallatheena amanoomaAAahu birahmatin minna wanajjaynahum minAAathabin ghaleeth","juz":12,"page":228},{"s":11,"a":59,"key":"11:59","ar":"وَتِلْكَ عَادٌ ۖ جَحَدُوا۟ بِـَٔايَـٰتِ رَبِّهِمْ وَعَصَوْا۟ رُسُلَهُۥ وَٱتَّبَعُوٓا۟ أَمْرَ كُلِّ جَبَّارٍ عَنِيدٍ","en":"And that was ʿAad, who rejected the signs of their Lord and disobeyed His messengers and followed the order of every obstinate tyrant.","tr":"Watilka AAadun jahadoo bi-ayatirabbihim waAAasaw rusulahu wattabaAAoo amra kullijabbarin AAaneed","juz":12,"page":228},{"s":11,"a":60,"key":"11:60","ar":"وَأُتْبِعُوا۟ فِى هَـٰذِهِ ٱلدُّنْيَا لَعْنَةً وَيَوْمَ ٱلْقِيَـٰمَةِ ۗ أَلَآ إِنَّ عَادًا كَفَرُوا۟ رَبَّهُمْ ۗ أَلَا بُعْدًا لِّعَادٍ قَوْمِ هُودٍ","en":"And they were [therefore] followed in this world with a curse and [as well] on the Day of Resurrection. Unquestionably, ʿAad denied their Lord; then away with ʿAad, the people of Hūd.","tr":"WaotbiAAoo fee hathihi addunyalaAAnatan wayawma alqiyamati ala inna AAadankafaroo rabbahum ala buAAdan liAAadin qawmi hood","juz":12,"page":228},{"s":11,"a":61,"key":"11:61","ar":"۞ وَإِلَىٰ ثَمُودَ أَخَاهُمْ صَـٰلِحًا ۚ قَالَ يَـٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَـٰهٍ غَيْرُهُۥ ۖ هُوَ أَنشَأَكُم مِّنَ ٱلْأَرْضِ وَٱسْتَعْمَرَكُمْ فِيهَا فَٱسْتَغْفِرُوهُ ثُمَّ تُوبُوٓا۟ إِلَيْهِ ۚ إِنَّ رَبِّى قَرِيبٌ مُّجِيبٌ","en":"And to Thamūd [We sent] their brother Ṣāliḥ. He said, \"O my people, worship Allāh; you have no deity other than Him. He has produced you from the earth and settled you in it, so ask forgiveness of Him and then repent to Him. Indeed, my Lord is near and responsive.\"","tr":"Wa-ila thamooda akhahum salihanqala ya qawmi oAAbudoo Allaha malakum min ilahin ghayruhu huwa anshaakum mina al-ardiwastaAAmarakum feeha fastaghfiroohu thummatooboo ilayhi inna rabbee qareebun mujeeb","juz":12,"page":228},{"s":11,"a":62,"key":"11:62","ar":"قَالُوا۟ يَـٰصَـٰلِحُ قَدْ كُنتَ فِينَا مَرْجُوًّا قَبْلَ هَـٰذَآ ۖ أَتَنْهَىٰنَآ أَن نَّعْبُدَ مَا يَعْبُدُ ءَابَآؤُنَا وَإِنَّنَا لَفِى شَكٍّ مِّمَّا تَدْعُونَآ إِلَيْهِ مُرِيبٍ","en":"They said, \"O Ṣāliḥ, you were among us a man of promise before this. Do you forbid us to worship what our fathers worshipped? And indeed we are, about that to which you invite us, in disquieting doubt.\"","tr":"Qaloo ya salihuqad kunta feena marjuwwan qabla hatha atanhanaan naAAbuda ma yaAAbudu abaonawa-innana lafee shakkin mimma tadAAoonailayhi mureeb","juz":12,"page":228},{"s":11,"a":63,"key":"11:63","ar":"قَالَ يَـٰقَوْمِ أَرَءَيْتُمْ إِن كُنتُ عَلَىٰ بَيِّنَةٍ مِّن رَّبِّى وَءَاتَىٰنِى مِنْهُ رَحْمَةً فَمَن يَنصُرُنِى مِنَ ٱللَّهِ إِنْ عَصَيْتُهُۥ ۖ فَمَا تَزِيدُونَنِى غَيْرَ تَخْسِيرٍ","en":"He said, \"O my people, have you considered: if I should be upon clear evidence from my Lord and He has given me mercy from Himself, who would protect me from Allāh if I disobeyed Him? So you would not increase me except in loss.","tr":"Qala ya qawmi araaytum inkuntu AAala bayyinatin min rabbee waataneeminhu rahmatan faman yansurunee mina Allahiin AAasaytuhu fama tazeedoonanee ghayra takhseer","juz":12,"page":229},{"s":11,"a":64,"key":"11:64","ar":"وَيَـٰقَوْمِ هَـٰذِهِۦ نَاقَةُ ٱللَّهِ لَكُمْ ءَايَةً فَذَرُوهَا تَأْكُلْ فِىٓ أَرْضِ ٱللَّهِ وَلَا تَمَسُّوهَا بِسُوٓءٍ فَيَأْخُذَكُمْ عَذَابٌ قَرِيبٌ","en":"And O my people, this is the she-camel of Allāh - [she is] to you a sign. So let her feed upon Allāh's earth and do not touch her with harm, or you will be taken by an impending punishment.\"","tr":"Waya qawmi hathihi naqatuAllahi lakum ayatan fatharooha ta/kulfee ardi Allahi wala tamassoohabisoo-in faya/khuthakum AAathabun qareeb","juz":12,"page":229},{"s":11,"a":65,"key":"11:65","ar":"فَعَقَرُوهَا فَقَالَ تَمَتَّعُوا۟ فِى دَارِكُمْ ثَلَـٰثَةَ أَيَّامٍ ۖ ذَٰلِكَ وَعْدٌ غَيْرُ مَكْذُوبٍ","en":"But they hamstrung her, so he said, \"Enjoy yourselves in your homes for three days. That is a promise not to be denied [i.e., unfailing].\"","tr":"FaAAaqarooha faqalatamattaAAoo fee darikum thalathata ayyamin thalikawaAAdun ghayru makthoob","juz":12,"page":229},{"s":11,"a":66,"key":"11:66","ar":"فَلَمَّا جَآءَ أَمْرُنَا نَجَّيْنَا صَـٰلِحًا وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ بِرَحْمَةٍ مِّنَّا وَمِنْ خِزْىِ يَوْمِئِذٍ ۗ إِنَّ رَبَّكَ هُوَ ٱلْقَوِىُّ ٱلْعَزِيزُ","en":"So when Our command came, We saved Ṣāliḥ and those who believed with him, by mercy from Us, and [saved them] from the disgrace of that day.1 Indeed, it is your Lord who is the Powerful, the Exalted in Might.","tr":"Falamma jaa amrunanajjayna salihan wallatheena amanoomaAAahu birahmatin minna wamin khizyi yawmi-ithininna rabbaka huwa alqawiyyu alAAazeez","juz":12,"page":229},{"s":11,"a":67,"key":"11:67","ar":"وَأَخَذَ ٱلَّذِينَ ظَلَمُوا۟ ٱلصَّيْحَةُ فَأَصْبَحُوا۟ فِى دِيَـٰرِهِمْ جَـٰثِمِينَ","en":"And the shriek1 seized those who had wronged, and they became within their homes [corpses] fallen prone","tr":"Waakhatha allatheena thalamooassayhatu faasbahoo fee diyarihimjathimeen","juz":12,"page":229},{"s":11,"a":68,"key":"11:68","ar":"كَأَن لَّمْ يَغْنَوْا۟ فِيهَآ ۗ أَلَآ إِنَّ ثَمُودَا۟ كَفَرُوا۟ رَبَّهُمْ ۗ أَلَا بُعْدًا لِّثَمُودَ","en":"As if they had never prospered therein. Unquestionably, Thamūd denied their Lord; then, away with Thamūd.","tr":"Kaan lam yaghnaw feeha alainna thamooda kafaroo rabbahum ala buAAdan lithamood","juz":12,"page":229},{"s":11,"a":69,"key":"11:69","ar":"وَلَقَدْ جَآءَتْ رُسُلُنَآ إِبْرَٰهِيمَ بِٱلْبُشْرَىٰ قَالُوا۟ سَلَـٰمًا ۖ قَالَ سَلَـٰمٌ ۖ فَمَا لَبِثَ أَن جَآءَ بِعِجْلٍ حَنِيذٍ","en":"And certainly did Our messengers [i.e., angels] come to Abraham with good tidings; they said, \"Peace.\" He said, \"Peace,\" and did not delay in bringing [them] a roasted calf.","tr":"Walaqad jaat rusuluna ibraheemabilbushra qaloo salaman qalasalamun fama labitha an jaa biAAijlin haneeth","juz":12,"page":229},{"s":11,"a":70,"key":"11:70","ar":"فَلَمَّا رَءَآ أَيْدِيَهُمْ لَا تَصِلُ إِلَيْهِ نَكِرَهُمْ وَأَوْجَسَ مِنْهُمْ خِيفَةً ۚ قَالُوا۟ لَا تَخَفْ إِنَّآ أُرْسِلْنَآ إِلَىٰ قَوْمِ لُوطٍ","en":"But when he saw their hands not reaching for it, he distrusted them and felt from them apprehension.1 They said, \"Fear not. We have been sent to the people of Lot.\"","tr":"Falamma raa aydiyahum latasilu ilayhi nakirahum waawjasa minhum kheefatan qaloola takhaf inna orsilna ila qawmi loot","juz":12,"page":229},{"s":11,"a":71,"key":"11:71","ar":"وَٱمْرَأَتُهُۥ قَآئِمَةٌ فَضَحِكَتْ فَبَشَّرْنَـٰهَا بِإِسْحَـٰقَ وَمِن وَرَآءِ إِسْحَـٰقَ يَعْقُوبَ","en":"And his wife was standing, and she smiled.1 Then We gave her good tidings of Isaac and after Isaac, Jacob.","tr":"Wamraatuhu qa-imatun fadahikatfabashsharnaha bi-ishaqa wamin wara-iishaqa yaAAqoob","juz":12,"page":229},{"s":11,"a":72,"key":"11:72","ar":"قَالَتْ يَـٰوَيْلَتَىٰٓ ءَأَلِدُ وَأَنَا۠ عَجُوزٌ وَهَـٰذَا بَعْلِى شَيْخًا ۖ إِنَّ هَـٰذَا لَشَىْءٌ عَجِيبٌ","en":"She said, \"Woe to me!1 Shall I give birth while I am an old woman and this, my husband, is an old man? Indeed, this is an amazing thing!\"","tr":"Qalat ya waylata aaliduwaana AAajoozun wahatha baAAlee shaykhan inna hathalashay-on AAajeeb","juz":12,"page":230},{"s":11,"a":73,"key":"11:73","ar":"قَالُوٓا۟ أَتَعْجَبِينَ مِنْ أَمْرِ ٱللَّهِ ۖ رَحْمَتُ ٱللَّهِ وَبَرَكَـٰتُهُۥ عَلَيْكُمْ أَهْلَ ٱلْبَيْتِ ۚ إِنَّهُۥ حَمِيدٌ مَّجِيدٌ","en":"They said, \"Are you amazed at the decree of Allāh? May the mercy of Allāh and His blessings be upon you, people of the house. Indeed, He is Praiseworthy and Honorable.\"","tr":"Qaloo ataAAjabeena min amri Allahirahmatu Allahi wabarakatuhu AAalaykum ahlaalbayti innahu hameedun majeed","juz":12,"page":230},{"s":11,"a":74,"key":"11:74","ar":"فَلَمَّا ذَهَبَ عَنْ إِبْرَٰهِيمَ ٱلرَّوْعُ وَجَآءَتْهُ ٱلْبُشْرَىٰ يُجَـٰدِلُنَا فِى قَوْمِ لُوطٍ","en":"And when the fright had left Abraham and the good tidings had reached him, he began to argue [i.e., plead] with Us1 concerning the people of Lot.","tr":"Falamma thahaba AAan ibraheemaarrawAAu wajaat-hu albushra yujadilunafee qawmi loot","juz":12,"page":230},{"s":11,"a":75,"key":"11:75","ar":"إِنَّ إِبْرَٰهِيمَ لَحَلِيمٌ أَوَّٰهٌ مُّنِيبٌ","en":"Indeed, Abraham was forbearing, grieving1 and [frequently] returning [to Allāh].","tr":"Inna ibraheema lahaleemun awwahunmuneeb","juz":12,"page":230},{"s":11,"a":76,"key":"11:76","ar":"يَـٰٓإِبْرَٰهِيمُ أَعْرِضْ عَنْ هَـٰذَآ ۖ إِنَّهُۥ قَدْ جَآءَ أَمْرُ رَبِّكَ ۖ وَإِنَّهُمْ ءَاتِيهِمْ عَذَابٌ غَيْرُ مَرْدُودٍ","en":"[The angels said], \"O Abraham, give up this [plea]. Indeed, the command of your Lord has come, and indeed, there will reach them a punishment that cannot be repelled.\"","tr":"Ya ibraheemu aAAridAAan hatha innahu qad jaa amru rabbika wa-innahum ateehimAAathabun ghayru mardood","juz":12,"page":230},{"s":11,"a":77,"key":"11:77","ar":"وَلَمَّا جَآءَتْ رُسُلُنَا لُوطًا سِىٓءَ بِهِمْ وَضَاقَ بِهِمْ ذَرْعًا وَقَالَ هَـٰذَا يَوْمٌ عَصِيبٌ","en":"And when Our messengers, [the angels], came to Lot, he was anguished for them and felt for them great discomfort1 and said, \"This is a trying day.\"","tr":"Walamma jaat rusulunalootan see-a bihim wadaqa bihim tharAAan waqalahatha yawmun AAaseeb","juz":12,"page":230},{"s":11,"a":78,"key":"11:78","ar":"وَجَآءَهُۥ قَوْمُهُۥ يُهْرَعُونَ إِلَيْهِ وَمِن قَبْلُ كَانُوا۟ يَعْمَلُونَ ٱلسَّيِّـَٔاتِ ۚ قَالَ يَـٰقَوْمِ هَـٰٓؤُلَآءِ بَنَاتِى هُنَّ أَطْهَرُ لَكُمْ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَلَا تُخْزُونِ فِى ضَيْفِىٓ ۖ أَلَيْسَ مِنكُمْ رَجُلٌ رَّشِيدٌ","en":"And his people came hastening to him, and before [this] they had been doing evil deeds.1 He said, \"O my people, these are my daughters;2 they are purer for you. So fear Allāh and do not disgrace me concerning my guests. Is there not among you a man of reason?\"","tr":"Wajaahu qawmuhu yuhraAAoona ilayhiwamin qablu kanoo yaAAmaloona assayyi-ati qalaya qawmi haola-i banatee hunna atharulakum fattaqoo Allaha wala tukhzooni fee dayfeealaysa minkum rajulun rasheed","juz":12,"page":230},{"s":11,"a":79,"key":"11:79","ar":"قَالُوا۟ لَقَدْ عَلِمْتَ مَا لَنَا فِى بَنَاتِكَ مِنْ حَقٍّ وَإِنَّكَ لَتَعْلَمُ مَا نُرِيدُ","en":"They said, \"You have already known that we have not concerning your daughters [i.e., women] any claim [i.e., desire], and indeed, you know what we want.\"","tr":"Qaloo laqad AAalimta ma lanafee banatika min haqqin wa-innaka lataAAlamu manureed","juz":12,"page":230},{"s":11,"a":80,"key":"11:80","ar":"قَالَ لَوْ أَنَّ لِى بِكُمْ قُوَّةً أَوْ ءَاوِىٓ إِلَىٰ رُكْنٍ شَدِيدٍ","en":"He said, \"If only I had against you some power or could take refuge in a strong support.\"","tr":"Qala law anna lee bikum quwwatan aw aweeila ruknin shadeed","juz":12,"page":230},{"s":11,"a":81,"key":"11:81","ar":"قَالُوا۟ يَـٰلُوطُ إِنَّا رُسُلُ رَبِّكَ لَن يَصِلُوٓا۟ إِلَيْكَ ۖ فَأَسْرِ بِأَهْلِكَ بِقِطْعٍ مِّنَ ٱلَّيْلِ وَلَا يَلْتَفِتْ مِنكُمْ أَحَدٌ إِلَّا ٱمْرَأَتَكَ ۖ إِنَّهُۥ مُصِيبُهَا مَآ أَصَابَهُمْ ۚ إِنَّ مَوْعِدَهُمُ ٱلصُّبْحُ ۚ أَلَيْسَ ٱلصُّبْحُ بِقَرِيبٍ","en":"They [the angels] said, \"O Lot, indeed we are messengers of your Lord; [therefore], they will never reach you. So set out with your family during a portion of the night1 and let not any among you look back - except your wife; indeed, she will be struck by that which strikes them. Indeed, their appointment is [for] the morning. Is not the morning near?\"","tr":"Qaloo ya lootu innarusulu rabbika lan yasiloo ilayka faasri bi-ahlika biqitAAinmina allayli wala yaltafit minkum ahadun illaimraataka innahu museebuha ma asabahuminna mawAAidahumu assubhu alaysa assubhubiqareeb","juz":12,"page":230},{"s":11,"a":82,"key":"11:82","ar":"فَلَمَّا جَآءَ أَمْرُنَا جَعَلْنَا عَـٰلِيَهَا سَافِلَهَا وَأَمْطَرْنَا عَلَيْهَا حِجَارَةً مِّن سِجِّيلٍ مَّنضُودٍ","en":"So when Our command came, We made the highest part [of the city] its lowest and rained upon them stones of layered hard clay, [which were]","tr":"Falamma jaa amrunajaAAalna AAaliyaha safilahawaamtarna AAalayha hijaratanmin sijjeelin mandood","juz":12,"page":231},{"s":11,"a":83,"key":"11:83","ar":"مُّسَوَّمَةً عِندَ رَبِّكَ ۖ وَمَا هِىَ مِنَ ٱلظَّـٰلِمِينَ بِبَعِيدٍ","en":"Marked from your Lord. And it [i.e., Allāh's punishment] is not from the wrongdoers [very] far.","tr":"Musawwamatan AAinda rabbika wama hiyamina aththalimeena bibaAAeed","juz":12,"page":231},{"s":11,"a":84,"key":"11:84","ar":"۞ وَإِلَىٰ مَدْيَنَ أَخَاهُمْ شُعَيْبًا ۚ قَالَ يَـٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَـٰهٍ غَيْرُهُۥ ۖ وَلَا تَنقُصُوا۟ ٱلْمِكْيَالَ وَٱلْمِيزَانَ ۚ إِنِّىٓ أَرَىٰكُم بِخَيْرٍ وَإِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ مُّحِيطٍ","en":"And to Madyan [We sent] their brother Shuʿayb. He said, \"O my people, worship Allāh; you have no deity other than Him. And do not decrease from the measure and the scale. Indeed, I see you in prosperity, but indeed, I fear for you the punishment of an all-encompassing Day.","tr":"Wa-ila madyana akhahumshuAAayban qala ya qawmi oAAbudoo Allaha malakum min ilahin ghayruhu wala tanqusooalmikyala walmeezana innee arakumbikhayrin wa-innee akhafu AAalaykum AAathaba yawminmuheet","juz":12,"page":231},{"s":11,"a":85,"key":"11:85","ar":"وَيَـٰقَوْمِ أَوْفُوا۟ ٱلْمِكْيَالَ وَٱلْمِيزَانَ بِٱلْقِسْطِ ۖ وَلَا تَبْخَسُوا۟ ٱلنَّاسَ أَشْيَآءَهُمْ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ","en":"And O my people, give full measure and weight in justice and do not deprive the people of their due and do not commit abuse on the earth, spreading corruption.","tr":"Waya qawmi awfoo almikyala walmeezanabilqisti wala tabkhasoo annasaashyaahum wala taAAthaw fee al-ardimufsideen","juz":12,"page":231},{"s":11,"a":86,"key":"11:86","ar":"بَقِيَّتُ ٱللَّهِ خَيْرٌ لَّكُمْ إِن كُنتُم مُّؤْمِنِينَ ۚ وَمَآ أَنَا۠ عَلَيْكُم بِحَفِيظٍ","en":"What remains [lawful] from Allāh is best for you, if you would be believers. But I am not a guardian over you.\"","tr":"Baqiyyatu Allahi khayrun lakum inkuntum mu/mineena wama ana AAalaykum bihafeeth","juz":12,"page":231},{"s":11,"a":87,"key":"11:87","ar":"قَالُوا۟ يَـٰشُعَيْبُ أَصَلَوٰتُكَ تَأْمُرُكَ أَن نَّتْرُكَ مَا يَعْبُدُ ءَابَآؤُنَآ أَوْ أَن نَّفْعَلَ فِىٓ أَمْوَٰلِنَا مَا نَشَـٰٓؤُا۟ ۖ إِنَّكَ لَأَنتَ ٱلْحَلِيمُ ٱلرَّشِيدُ","en":"They said, \"O Shuʿayb, does your prayer [i.e., religion] command you that we should leave what our fathers worship or not do with our wealth what we please? Indeed, you are the forbearing, the discerning!\"1","tr":"Qaloo ya shuAAaybu asalatukata/muruka an natruka ma yaAAbudu abaonaaw an nafAAala fee amwalina ma nashaoinnaka laanta alhaleemu arrasheed","juz":12,"page":231},{"s":11,"a":88,"key":"11:88","ar":"قَالَ يَـٰقَوْمِ أَرَءَيْتُمْ إِن كُنتُ عَلَىٰ بَيِّنَةٍ مِّن رَّبِّى وَرَزَقَنِى مِنْهُ رِزْقًا حَسَنًا ۚ وَمَآ أُرِيدُ أَنْ أُخَالِفَكُمْ إِلَىٰ مَآ أَنْهَىٰكُمْ عَنْهُ ۚ إِنْ أُرِيدُ إِلَّا ٱلْإِصْلَـٰحَ مَا ٱسْتَطَعْتُ ۚ وَمَا تَوْفِيقِىٓ إِلَّا بِٱللَّهِ ۚ عَلَيْهِ تَوَكَّلْتُ وَإِلَيْهِ أُنِيبُ","en":"He said, \"O my people, have you considered: if I am upon clear evidence from my Lord and He has provided me with a good provision from Him...?1 And I do not intend to differ from you in that which I have forbidden you; I only intend reform as much as I am able. And my success is not but through Allāh. Upon Him I have relied, and to Him I return.2","tr":"Qala ya qawmi araaytum inkuntu AAala bayyinatin min rabbee warazaqanee minhu rizqanhasanan wama oreedu an okhalifakum ilama anhakum AAanhu in oreedu illa al-islahama istataAAtu wama tawfeeqee illa billahiAAalayhi tawakkaltu wa-ilayhi oneeb","juz":12,"page":231},{"s":11,"a":89,"key":"11:89","ar":"وَيَـٰقَوْمِ لَا يَجْرِمَنَّكُمْ شِقَاقِىٓ أَن يُصِيبَكُم مِّثْلُ مَآ أَصَابَ قَوْمَ نُوحٍ أَوْ قَوْمَ هُودٍ أَوْ قَوْمَ صَـٰلِحٍ ۚ وَمَا قَوْمُ لُوطٍ مِّنكُم بِبَعِيدٍ","en":"And O my people, let not [your] dissension from me cause you to be struck by that similar to what struck the people of Noah or the people of Hūd or the people of Ṣāliḥ. And the people of Lot are not from you far away.","tr":"Waya qawmi la yajrimannakumshiqaqee an yuseebakum mithlu ma asabaqawma noohin aw qawma hoodin aw qawma salihinwama qawmu lootin minkum bibaAAeed","juz":12,"page":232},{"s":11,"a":90,"key":"11:90","ar":"وَٱسْتَغْفِرُوا۟ رَبَّكُمْ ثُمَّ تُوبُوٓا۟ إِلَيْهِ ۚ إِنَّ رَبِّى رَحِيمٌ وَدُودٌ","en":"And ask forgiveness of your Lord and then repent to Him. Indeed, my Lord is Merciful and Affectionate.\"","tr":"Wastaghfiroo rabbakum thumma toobooilayhi inna rabbee raheemun wadood","juz":12,"page":232},{"s":11,"a":91,"key":"11:91","ar":"قَالُوا۟ يَـٰشُعَيْبُ مَا نَفْقَهُ كَثِيرًا مِّمَّا تَقُولُ وَإِنَّا لَنَرَىٰكَ فِينَا ضَعِيفًا ۖ وَلَوْلَا رَهْطُكَ لَرَجَمْنَـٰكَ ۖ وَمَآ أَنتَ عَلَيْنَا بِعَزِيزٍ","en":"They said, \"O Shuʿayb, we do not understand much of what you say, and indeed, we consider you among us as weak. And if not for your family, we would have stoned you [to death]; and you are not to us one respected.\"","tr":"Qaloo ya shuAAaybu manafqahu katheeran mimma taqoolu wa-inna lanarakafeena daAAeefan walawla rahtukalarajamnaka wama anta AAalayna biAAazeez","juz":12,"page":232},{"s":11,"a":92,"key":"11:92","ar":"قَالَ يَـٰقَوْمِ أَرَهْطِىٓ أَعَزُّ عَلَيْكُم مِّنَ ٱللَّهِ وَٱتَّخَذْتُمُوهُ وَرَآءَكُمْ ظِهْرِيًّا ۖ إِنَّ رَبِّى بِمَا تَعْمَلُونَ مُحِيطٌ","en":"He said, \"O my people, is my family more respected for power by you than Allāh? But you put Him behind your backs [in neglect]. Indeed, my Lord is encompassing of what you do.","tr":"Qala ya qawmi arahteeaAAazzu AAalaykum mina Allahi wattakhathtumoohuwaraakum thihriyyan inna rabbee bimataAAmaloona muheet","juz":12,"page":232},{"s":11,"a":93,"key":"11:93","ar":"وَيَـٰقَوْمِ ٱعْمَلُوا۟ عَلَىٰ مَكَانَتِكُمْ إِنِّى عَـٰمِلٌ ۖ سَوْفَ تَعْلَمُونَ مَن يَأْتِيهِ عَذَابٌ يُخْزِيهِ وَمَنْ هُوَ كَـٰذِبٌ ۖ وَٱرْتَقِبُوٓا۟ إِنِّى مَعَكُمْ رَقِيبٌ","en":"And O my people, work according to your position; indeed, I am working. You are going to know to whom will come a punishment that will disgrace him and who is a liar. So watch; indeed, I am with you a watcher, [awaiting the outcome].\"","tr":"Waya qawmi iAAmaloo AAala makanatikuminnee AAamilun sawfa taAAlamoona man ya/teehi AAathabunyukhzeehi waman huwa kathibun wartaqiboo innemaAAakum raqeeb","juz":12,"page":232},{"s":11,"a":94,"key":"11:94","ar":"وَلَمَّا جَآءَ أَمْرُنَا نَجَّيْنَا شُعَيْبًا وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ بِرَحْمَةٍ مِّنَّا وَأَخَذَتِ ٱلَّذِينَ ظَلَمُوا۟ ٱلصَّيْحَةُ فَأَصْبَحُوا۟ فِى دِيَـٰرِهِمْ جَـٰثِمِينَ","en":"And when Our command came, We saved Shuʿayb and those who believed with him, by mercy from Us. And the shriek seized those who had wronged, and they became within their homes [corpses] fallen prone","tr":"Walamma jaa amrunanajjayna shuAAayban wallatheena amanoomaAAahu birahmatin minna waakhathati allatheenathalamoo assayhatu faasbahoofee diyarihim jathimeen","juz":12,"page":232},{"s":11,"a":95,"key":"11:95","ar":"كَأَن لَّمْ يَغْنَوْا۟ فِيهَآ ۗ أَلَا بُعْدًا لِّمَدْيَنَ كَمَا بَعِدَتْ ثَمُودُ","en":"As if they had never prospered therein. Then, away with Madyan as Thamūd was taken away.","tr":"Kaan lam yaghnaw feeha alabuAAdan limadyana kama baAAidat thamood","juz":12,"page":232},{"s":11,"a":96,"key":"11:96","ar":"وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِـَٔايَـٰتِنَا وَسُلْطَـٰنٍ مُّبِينٍ","en":"And We did certainly send Moses with Our signs and a clear authority1","tr":"Walaqad arsalna moosa bi-ayatinawasultanin mubeen","juz":12,"page":232},{"s":11,"a":97,"key":"11:97","ar":"إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَٱتَّبَعُوٓا۟ أَمْرَ فِرْعَوْنَ ۖ وَمَآ أَمْرُ فِرْعَوْنَ بِرَشِيدٍ","en":"To Pharaoh and his establishment, but they followed the command of Pharaoh, and the command of Pharaoh was not [at all] discerning.","tr":"Ila firAAawna wamala-ihi fattabaAAooamra firAAawna wama amru firAAawna birasheed","juz":12,"page":232},{"s":11,"a":98,"key":"11:98","ar":"يَقْدُمُ قَوْمَهُۥ يَوْمَ ٱلْقِيَـٰمَةِ فَأَوْرَدَهُمُ ٱلنَّارَ ۖ وَبِئْسَ ٱلْوِرْدُ ٱلْمَوْرُودُ","en":"He will precede his people on the Day of Resurrection and lead them into the Fire; and wretched is the place to which they are led.","tr":"Yaqdumu qawmahu yawma alqiyamatifaawradahumu annara wabi/sa alwirdu almawrood","juz":12,"page":233},{"s":11,"a":99,"key":"11:99","ar":"وَأُتْبِعُوا۟ فِى هَـٰذِهِۦ لَعْنَةً وَيَوْمَ ٱلْقِيَـٰمَةِ ۚ بِئْسَ ٱلرِّفْدُ ٱلْمَرْفُودُ","en":"And they were followed in this [world] with a curse and on the Day of Resurrection. And wretched is the gift1 which is given.","tr":"WaotbiAAoo fee hathihi laAAnatanwayawma alqiyamati bi/sa arrifdu almarfood","juz":12,"page":233},{"s":11,"a":100,"key":"11:100","ar":"ذَٰلِكَ مِنْ أَنۢبَآءِ ٱلْقُرَىٰ نَقُصُّهُۥ عَلَيْكَ ۖ مِنْهَا قَآئِمٌ وَحَصِيدٌ","en":"That is from the news of the cities, which We relate to you; of them, some are [still] standing and some are [as] a harvest [mowed down].1","tr":"Thalika min anba-i alquranaqussuhu AAalayka minha qa-imun wahaseed","juz":12,"page":233},{"s":11,"a":101,"key":"11:101","ar":"وَمَا ظَلَمْنَـٰهُمْ وَلَـٰكِن ظَلَمُوٓا۟ أَنفُسَهُمْ ۖ فَمَآ أَغْنَتْ عَنْهُمْ ءَالِهَتُهُمُ ٱلَّتِى يَدْعُونَ مِن دُونِ ٱللَّهِ مِن شَىْءٍ لَّمَّا جَآءَ أَمْرُ رَبِّكَ ۖ وَمَا زَادُوهُمْ غَيْرَ تَتْبِيبٍ","en":"And We did not wrong them, but they wronged themselves. And they were not availed at all by their gods which they invoked other than Allāh when there came the command of your Lord. And they did not increase them in other than ruin.","tr":"Wama thalamnahumwalakin thalamoo anfusahum famaaghnat AAanhum alihatuhumu allatee yadAAoona min dooni Allahimin shay-in lamma jaa amru rabbika wama zadoohumghayra tatbeeb","juz":12,"page":233},{"s":11,"a":102,"key":"11:102","ar":"وَكَذَٰلِكَ أَخْذُ رَبِّكَ إِذَآ أَخَذَ ٱلْقُرَىٰ وَهِىَ ظَـٰلِمَةٌ ۚ إِنَّ أَخْذَهُۥٓ أَلِيمٌ شَدِيدٌ","en":"And thus is the seizure of your Lord when He seizes the cities while they are committing wrong. Indeed, His seizure is painful and severe.","tr":"Wakathalika akhthu rabbika ithaakhatha alqura wahiya thalimatuninna akhthahu aleemun shadeed","juz":12,"page":233},{"s":11,"a":103,"key":"11:103","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّمَنْ خَافَ عَذَابَ ٱلْـَٔاخِرَةِ ۚ ذَٰلِكَ يَوْمٌ مَّجْمُوعٌ لَّهُ ٱلنَّاسُ وَذَٰلِكَ يَوْمٌ مَّشْهُودٌ","en":"Indeed in that is a sign for those who fear the punishment of the Hereafter. That is a Day for which the people will be collected, and that is a Day [which will be] witnessed.","tr":"Inna fee thalika laayatanliman khafa AAathaba al-akhirati thalikayawmun majmooAAun lahu annasu wathalikayawmun mashhoodun","juz":12,"page":233},{"s":11,"a":104,"key":"11:104","ar":"وَمَا نُؤَخِّرُهُۥٓ إِلَّا لِأَجَلٍ مَّعْدُودٍ","en":"And We do not delay it except for a limited term.","tr":"Wama nu-akhkhiruhu illali-ajalin maAAdood","juz":12,"page":233},{"s":11,"a":105,"key":"11:105","ar":"يَوْمَ يَأْتِ لَا تَكَلَّمُ نَفْسٌ إِلَّا بِإِذْنِهِۦ ۚ فَمِنْهُمْ شَقِىٌّ وَسَعِيدٌ","en":"The Day it comes no soul will speak except by His permission. And among them will be the wretched and the prosperous.","tr":"Yawma ya/ti la takallamu nafsun illabi-ithnihi faminhum shaqiyyun wasaAAeed","juz":12,"page":233},{"s":11,"a":106,"key":"11:106","ar":"فَأَمَّا ٱلَّذِينَ شَقُوا۟ فَفِى ٱلنَّارِ لَهُمْ فِيهَا زَفِيرٌ وَشَهِيقٌ","en":"As for those who were [destined to be] wretched, they will be in the Fire. For them therein is [violent] exhaling and inhaling.1","tr":"Faamma allatheena shaqoofafee annari lahum feeha zafeerun washaheeq","juz":12,"page":233},{"s":11,"a":107,"key":"11:107","ar":"خَـٰلِدِينَ فِيهَا مَا دَامَتِ ٱلسَّمَـٰوَٰتُ وَٱلْأَرْضُ إِلَّا مَا شَآءَ رَبُّكَ ۚ إِنَّ رَبَّكَ فَعَّالٌ لِّمَا يُرِيدُ","en":"[They will be] abiding therein as long as the heavens and the earth endure, except what your Lord should will. Indeed, your Lord is an effecter of what He intends.","tr":"Khalideena feeha ma damatiassamawatu wal-ardu illama shaa rabbuka inna rabbaka faAAAAalun limayureed","juz":12,"page":233},{"s":11,"a":108,"key":"11:108","ar":"۞ وَأَمَّا ٱلَّذِينَ سُعِدُوا۟ فَفِى ٱلْجَنَّةِ خَـٰلِدِينَ فِيهَا مَا دَامَتِ ٱلسَّمَـٰوَٰتُ وَٱلْأَرْضُ إِلَّا مَا شَآءَ رَبُّكَ ۖ عَطَآءً غَيْرَ مَجْذُوذٍ","en":"And as for those who were [destined to be] prosperous, they will be in Paradise, abiding therein as long as the heavens and the earth endure, except what your Lord should will - a bestowal uninterrupted.","tr":"Waamma allatheena suAAidoofafee aljannati khalideena feeha ma damatiassamawatu wal-ardu illama shaa rabbuka AAataan ghayra majthooth","juz":12,"page":233},{"s":11,"a":109,"key":"11:109","ar":"فَلَا تَكُ فِى مِرْيَةٍ مِّمَّا يَعْبُدُ هَـٰٓؤُلَآءِ ۚ مَا يَعْبُدُونَ إِلَّا كَمَا يَعْبُدُ ءَابَآؤُهُم مِّن قَبْلُ ۚ وَإِنَّا لَمُوَفُّوهُمْ نَصِيبَهُمْ غَيْرَ مَنقُوصٍ","en":"So do not be in doubt, [O Muḥammad], as to what these [polytheists] are worshipping. They worship not except as their fathers worshipped before. And indeed, We will give them their share undiminished.","tr":"Fala taku fee miryatin mimmayaAAbudu haola-i ma yaAAbudoona illakama yaAAbudu abaohum min qablu wa-innalamuwaffoohum naseebahum ghayra manqoos","juz":12,"page":234},{"s":11,"a":110,"key":"11:110","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ فَٱخْتُلِفَ فِيهِ ۚ وَلَوْلَا كَلِمَةٌ سَبَقَتْ مِن رَّبِّكَ لَقُضِىَ بَيْنَهُمْ ۚ وَإِنَّهُمْ لَفِى شَكٍّ مِّنْهُ مُرِيبٍ","en":"And We had certainly given Moses the Scripture, but it came under disagreement. And if not for a word1 that preceded from your Lord, it would have been judged between them. And indeed they are, concerning it [i.e., the Qur’ān], in disquieting doubt.","tr":"Walaqad atayna moosaalkitaba fakhtulifa feehi walawla kalimatunsabaqat min rabbika laqudiya baynahum wa-innahum lafeeshakkin minhu mureeb","juz":12,"page":234},{"s":11,"a":111,"key":"11:111","ar":"وَإِنَّ كُلًّا لَّمَّا لَيُوَفِّيَنَّهُمْ رَبُّكَ أَعْمَـٰلَهُمْ ۚ إِنَّهُۥ بِمَا يَعْمَلُونَ خَبِيرٌ","en":"And indeed, each [of the believers and disbelievers] - your Lord will fully compensate them for their deeds. Indeed, He is Aware of what they do.","tr":"Wa-inna kullan lammalayuwaffiyannahum rabbuka aAAmalahum innahu bimayaAAmaloona khabeer","juz":12,"page":234},{"s":11,"a":112,"key":"11:112","ar":"فَٱسْتَقِمْ كَمَآ أُمِرْتَ وَمَن تَابَ مَعَكَ وَلَا تَطْغَوْا۟ ۚ إِنَّهُۥ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"So remain on a right course as you have been commanded, [you] and those who have turned back with you [to Allāh], and do not transgress. Indeed, He is Seeing of what you do.","tr":"Fastaqim kama omirta waman tabamaAAaka wala tatghaw innahu bima taAAmaloonabaseer","juz":12,"page":234},{"s":11,"a":113,"key":"11:113","ar":"وَلَا تَرْكَنُوٓا۟ إِلَى ٱلَّذِينَ ظَلَمُوا۟ فَتَمَسَّكُمُ ٱلنَّارُ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِنْ أَوْلِيَآءَ ثُمَّ لَا تُنصَرُونَ","en":"And do not incline toward those who do wrong, lest you be touched by the Fire, and you would not have other than Allāh any protectors; then you would not be helped.","tr":"Wala tarkanoo ila allatheenathalamoo fatamassakumu annaru wamalakum min dooni Allahi min awliyaa thumma latunsaroon","juz":12,"page":234},{"s":11,"a":114,"key":"11:114","ar":"وَأَقِمِ ٱلصَّلَوٰةَ طَرَفَىِ ٱلنَّهَارِ وَزُلَفًا مِّنَ ٱلَّيْلِ ۚ إِنَّ ٱلْحَسَنَـٰتِ يُذْهِبْنَ ٱلسَّيِّـَٔاتِ ۚ ذَٰلِكَ ذِكْرَىٰ لِلذَّٰكِرِينَ","en":"And establish prayer at the two ends of the day and at the approach of the night. Indeed, good deeds do away with misdeeds. That is a reminder for those who remember.","tr":"Waaqimi assalata tarafayiannahari wazulafan mina allayli inna alhasanatiyuthhibna assayyi-ati thalika thikraliththakireen","juz":12,"page":234},{"s":11,"a":115,"key":"11:115","ar":"وَٱصْبِرْ فَإِنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ","en":"And be patient, for indeed, Allāh does not allow to be lost the reward of those who do good.","tr":"Wasbir fa-inna Allahala yudeeAAu ajra almuhsineen","juz":12,"page":234},{"s":11,"a":116,"key":"11:116","ar":"فَلَوْلَا كَانَ مِنَ ٱلْقُرُونِ مِن قَبْلِكُمْ أُو۟لُوا۟ بَقِيَّةٍ يَنْهَوْنَ عَنِ ٱلْفَسَادِ فِى ٱلْأَرْضِ إِلَّا قَلِيلًا مِّمَّنْ أَنجَيْنَا مِنْهُمْ ۗ وَٱتَّبَعَ ٱلَّذِينَ ظَلَمُوا۟ مَآ أُتْرِفُوا۟ فِيهِ وَكَانُوا۟ مُجْرِمِينَ","en":"So why were there not1 among the generations before you those of enduring discrimination forbidding corruption on earth - except a few of those We saved from among them? But those who wronged pursued what luxury they were given therein, and they were criminals.","tr":"Falawla kana mina alquroonimin qablikum oloo baqiyyatin yanhawna AAani alfasadi feeal-ardi illa qaleelan mimman anjayna minhumwattabaAAa allatheena thalamoo maotrifoo feehi wakanoo mujrimeen","juz":12,"page":234},{"s":11,"a":117,"key":"11:117","ar":"وَمَا كَانَ رَبُّكَ لِيُهْلِكَ ٱلْقُرَىٰ بِظُلْمٍ وَأَهْلُهَا مُصْلِحُونَ","en":"And your Lord would not have destroyed the cities unjustly while their people were reformers.","tr":"Wama kana rabbuka liyuhlikaalqura bithulmin waahluha muslihoon","juz":12,"page":234},{"s":11,"a":118,"key":"11:118","ar":"وَلَوْ شَآءَ رَبُّكَ لَجَعَلَ ٱلنَّاسَ أُمَّةً وَٰحِدَةً ۖ وَلَا يَزَالُونَ مُخْتَلِفِينَ","en":"And if your Lord had willed, He could have made mankind one community; but they will not cease to differ,","tr":"Walaw shaa rabbuka lajaAAala annasaommatan wahidatan wala yazaloonamukhtalifeen","juz":12,"page":235},{"s":11,"a":119,"key":"11:119","ar":"إِلَّا مَن رَّحِمَ رَبُّكَ ۚ وَلِذَٰلِكَ خَلَقَهُمْ ۗ وَتَمَّتْ كَلِمَةُ رَبِّكَ لَأَمْلَأَنَّ جَهَنَّمَ مِنَ ٱلْجِنَّةِ وَٱلنَّاسِ أَجْمَعِينَ","en":"Except whom your Lord has given mercy, and for that He created them. But the word of your Lord is to be fulfilled that, \"I will surely fill Hell with jinn and men all together.\"","tr":"Illa man rahima rabbuka walithalikakhalaqahum watammat kalimatu rabbika laamlaanna jahannama minaaljinnati wannasi ajmaAAeen","juz":12,"page":235},{"s":11,"a":120,"key":"11:120","ar":"وَكُلًّا نَّقُصُّ عَلَيْكَ مِنْ أَنۢبَآءِ ٱلرُّسُلِ مَا نُثَبِّتُ بِهِۦ فُؤَادَكَ ۚ وَجَآءَكَ فِى هَـٰذِهِ ٱلْحَقُّ وَمَوْعِظَةٌ وَذِكْرَىٰ لِلْمُؤْمِنِينَ","en":"And each [story] We relate to you from the news of the messengers is that by which We make firm your heart. And there has come to you, in this, the truth and an instruction and a reminder for the believers.","tr":"Wakullan naqussu AAalayka min anba-iarrusuli ma nuthabbitu bihi fu-adaka wajaakafee hathihi alhaqqu wamawAAithatun wathikralilmu/mineen","juz":12,"page":235},{"s":11,"a":121,"key":"11:121","ar":"وَقُل لِّلَّذِينَ لَا يُؤْمِنُونَ ٱعْمَلُوا۟ عَلَىٰ مَكَانَتِكُمْ إِنَّا عَـٰمِلُونَ","en":"And say to those who do not believe, \"Work according to your position; indeed, we are working.","tr":"Waqul lillatheena layu/minoona iAAmaloo AAala makanatikum innaAAamiloon","juz":12,"page":235},{"s":11,"a":122,"key":"11:122","ar":"وَٱنتَظِرُوٓا۟ إِنَّا مُنتَظِرُونَ","en":"And wait; indeed, we are waiting.\"","tr":"Wantathiroo innamuntathiroon","juz":12,"page":235},{"s":11,"a":123,"key":"11:123","ar":"وَلِلَّهِ غَيْبُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَإِلَيْهِ يُرْجَعُ ٱلْأَمْرُ كُلُّهُۥ فَٱعْبُدْهُ وَتَوَكَّلْ عَلَيْهِ ۚ وَمَا رَبُّكَ بِغَـٰفِلٍ عَمَّا تَعْمَلُونَ","en":"And to Allāh belong the unseen [aspects] of the heavens and the earth and to Him will be returned the matter, all of it, so worship Him and rely upon Him. And your Lord is not unaware of that which you do.","tr":"Walillahi ghaybu assamawatiwal-ardi wa-ilayhi yurjaAAu al-amru kulluhu faAAbudhuwatawakkal AAalayhi wama rabbuka bighafilin AAammataAAmaloon","juz":12,"page":235},{"s":12,"a":1,"key":"12:1","ar":" الٓر ۚ تِلْكَ ءَايَـٰتُ ٱلْكِتَـٰبِ ٱلْمُبِينِ","en":"Alif, Lām, Rā.1 These are the verses of the clear Book.","tr":"Alif-lam-ra tilka ayatualkitabi almubeen","juz":12,"page":235},{"s":12,"a":2,"key":"12:2","ar":"إِنَّآ أَنزَلْنَـٰهُ قُرْءَٰنًا عَرَبِيًّا لَّعَلَّكُمْ تَعْقِلُونَ","en":"Indeed, We have sent it down as an Arabic Qur’ān1 that you might understand.","tr":"Inna anzalnahu qur-ananAAarabiyyan laAAallakum taAAqiloon","juz":12,"page":235},{"s":12,"a":3,"key":"12:3","ar":"نَحْنُ نَقُصُّ عَلَيْكَ أَحْسَنَ ٱلْقَصَصِ بِمَآ أَوْحَيْنَآ إِلَيْكَ هَـٰذَا ٱلْقُرْءَانَ وَإِن كُنتَ مِن قَبْلِهِۦ لَمِنَ ٱلْغَـٰفِلِينَ","en":"We relate to you, [O Muḥammad], the best of stories in what We have revealed to you of this Qur’ān although you were, before it, among the unaware.","tr":"Nahnu naqussu AAalayka ahsanaalqasasi bima awhayna ilayka hathaalqur-ana wa-in kunta min qablihi lamina alghafileen","juz":12,"page":235},{"s":12,"a":4,"key":"12:4","ar":"إِذْ قَالَ يُوسُفُ لِأَبِيهِ يَـٰٓأَبَتِ إِنِّى رَأَيْتُ أَحَدَ عَشَرَ كَوْكَبًا وَٱلشَّمْسَ وَٱلْقَمَرَ رَأَيْتُهُمْ لِى سَـٰجِدِينَ","en":"[Of these stories mention] when Joseph said to his father,1 \"O my father, indeed I have seen [in a dream] eleven stars and the sun and the moon; I saw them prostrating to me.\"","tr":"Ith qala yoosufu li-abeehi yaabati innee raaytu ahada AAashara kawkaban washshamsawalqamara raaytuhum lee sajideen","juz":12,"page":235},{"s":12,"a":5,"key":"12:5","ar":"قَالَ يَـٰبُنَىَّ لَا تَقْصُصْ رُءْيَاكَ عَلَىٰٓ إِخْوَتِكَ فَيَكِيدُوا۟ لَكَ كَيْدًا ۖ إِنَّ ٱلشَّيْطَـٰنَ لِلْإِنسَـٰنِ عَدُوٌّ مُّبِينٌ","en":"He said, \"O my son, do not relate your vision to your brothers or they will contrive against you a plan. Indeed Satan, to man, is a manifest enemy.","tr":"Qala ya bunayya la taqsusru/yaka AAala ikhwatika fayakeedoo laka kaydan innaashshaytana lil-insani AAaduwwun mubeen","juz":12,"page":236},{"s":12,"a":6,"key":"12:6","ar":"وَكَذَٰلِكَ يَجْتَبِيكَ رَبُّكَ وَيُعَلِّمُكَ مِن تَأْوِيلِ ٱلْأَحَادِيثِ وَيُتِمُّ نِعْمَتَهُۥ عَلَيْكَ وَعَلَىٰٓ ءَالِ يَعْقُوبَ كَمَآ أَتَمَّهَا عَلَىٰٓ أَبَوَيْكَ مِن قَبْلُ إِبْرَٰهِيمَ وَإِسْحَـٰقَ ۚ إِنَّ رَبَّكَ عَلِيمٌ حَكِيمٌ","en":"And thus will your Lord choose you and teach you the interpretation of narratives [i.e., events or dreams] and complete His favor upon you and upon the family of Jacob, as He completed it upon your fathers before, Abraham and Isaac. Indeed, your Lord is Knowing and Wise.\"","tr":"Wakathalika yajtabeeka rabbukawayuAAallimuka min ta/weeli al-ahadeethi wayutimmuniAAmatahu AAalayka waAAala ali yaAAqooba kamaatammaha AAala abawayka min qablu ibraheemawa-ishaqa inna rabbaka AAaleemun hakeem","juz":12,"page":236},{"s":12,"a":7,"key":"12:7","ar":"۞ لَّقَدْ كَانَ فِى يُوسُفَ وَإِخْوَتِهِۦٓ ءَايَـٰتٌ لِّلسَّآئِلِينَ","en":"Certainly were there in Joseph and his brothers signs for those who ask, [such as]","tr":"Laqad kana fee yoosufa wa-ikhwatihi ayatunlissa-ileen","juz":12,"page":236},{"s":12,"a":8,"key":"12:8","ar":"إِذْ قَالُوا۟ لَيُوسُفُ وَأَخُوهُ أَحَبُّ إِلَىٰٓ أَبِينَا مِنَّا وَنَحْنُ عُصْبَةٌ إِنَّ أَبَانَا لَفِى ضَلَـٰلٍ مُّبِينٍ","en":"When they said, \"Joseph and his brother1 are more beloved to our father than we, while we are a clan. Indeed, our father is in clear error.","tr":"Ith qaloo layoosufu waakhoohu ahabbuila abeena minna wanahnu AAusbatuninna abana lafee dalalin mubeen","juz":12,"page":236},{"s":12,"a":9,"key":"12:9","ar":"ٱقْتُلُوا۟ يُوسُفَ أَوِ ٱطْرَحُوهُ أَرْضًا يَخْلُ لَكُمْ وَجْهُ أَبِيكُمْ وَتَكُونُوا۟ مِنۢ بَعْدِهِۦ قَوْمًا صَـٰلِحِينَ","en":"Kill Joseph or cast him out to [another] land; the countenance [i.e., attention] of your father will [then] be only for you, and you will be after that a righteous people.\"1","tr":"Oqtuloo yoosufa awi itrahoohuardan yakhlu lakum wajhu abeekum watakoonoo min baAAdihiqawman saliheen","juz":12,"page":236},{"s":12,"a":10,"key":"12:10","ar":"قَالَ قَآئِلٌ مِّنْهُمْ لَا تَقْتُلُوا۟ يُوسُفَ وَأَلْقُوهُ فِى غَيَـٰبَتِ ٱلْجُبِّ يَلْتَقِطْهُ بَعْضُ ٱلسَّيَّارَةِ إِن كُنتُمْ فَـٰعِلِينَ","en":"Said a speaker among them, \"Do not kill Joseph but throw him into the bottom of the well; some travelers will pick him up - if you would do [something].\"","tr":"Qala qa-ilun minhum lataqtuloo yoosufa waalqoohu fee ghayabati aljubbi yaltaqithubaAAdu assayyarati in kuntum faAAileen","juz":12,"page":236},{"s":12,"a":11,"key":"12:11","ar":"قَالُوا۟ يَـٰٓأَبَانَا مَا لَكَ لَا تَأْمَ۫نَّا عَلَىٰ يُوسُفَ وَإِنَّا لَهُۥ لَنَـٰصِحُونَ","en":"They said, \"O our father, why do you not entrust us with Joseph while indeed, we are to him sincere counselors?","tr":"Qaloo ya abana malaka la ta/manna AAala yoosufa wa-innalahu lanasihoon","juz":12,"page":236},{"s":12,"a":12,"key":"12:12","ar":"أَرْسِلْهُ مَعَنَا غَدًا يَرْتَعْ وَيَلْعَبْ وَإِنَّا لَهُۥ لَحَـٰفِظُونَ","en":"Send him with us tomorrow that he may eat well and play. And indeed, we will be his guardians.\"","tr":"Arsilhu maAAana ghadan yartaAAwayalAAab wa-inna lahu lahafithoon","juz":12,"page":236},{"s":12,"a":13,"key":"12:13","ar":"قَالَ إِنِّى لَيَحْزُنُنِىٓ أَن تَذْهَبُوا۟ بِهِۦ وَأَخَافُ أَن يَأْكُلَهُ ٱلذِّئْبُ وَأَنتُمْ عَنْهُ غَـٰفِلُونَ","en":"[Jacob] said, \"Indeed, it saddens me that you should take him, and I fear that a wolf would eat him while you are of him unaware.\"","tr":"Qala innee layahzununee an thathhaboobihi waakhafu an ya/kulahu aththi/buwaantum AAanhu ghafiloon","juz":12,"page":236},{"s":12,"a":14,"key":"12:14","ar":"قَالُوا۟ لَئِنْ أَكَلَهُ ٱلذِّئْبُ وَنَحْنُ عُصْبَةٌ إِنَّآ إِذًا لَّخَـٰسِرُونَ","en":"They said, \"If a wolf should eat him while we are a [strong] clan, indeed, we would then be losers.\"","tr":"Qaloo la-in akalahu aththi/buwanahnu AAusbatun inna ithan lakhasiroon","juz":12,"page":236},{"s":12,"a":15,"key":"12:15","ar":"فَلَمَّا ذَهَبُوا۟ بِهِۦ وَأَجْمَعُوٓا۟ أَن يَجْعَلُوهُ فِى غَيَـٰبَتِ ٱلْجُبِّ ۚ وَأَوْحَيْنَآ إِلَيْهِ لَتُنَبِّئَنَّهُم بِأَمْرِهِمْ هَـٰذَا وَهُمْ لَا يَشْعُرُونَ","en":"So when they took him [out] and agreed to put him into the bottom of the well...1 But We inspired to him, \"You will surely inform them [someday] about this affair of theirs while they do not perceive [your identity].\"","tr":"Falamma thahaboo bihiwaajmaAAoo an yajAAaloohu fee ghayabati aljubbi waawhaynailayhi latunabi-annahum bi-amrihim hatha wahum layashAAuroon","juz":12,"page":237},{"s":12,"a":16,"key":"12:16","ar":"وَجَآءُوٓ أَبَاهُمْ عِشَآءً يَبْكُونَ","en":"And they came to their father at night, weeping.","tr":"Wajaoo abahum AAishaanyabkoon","juz":12,"page":237},{"s":12,"a":17,"key":"12:17","ar":"قَالُوا۟ يَـٰٓأَبَانَآ إِنَّا ذَهَبْنَا نَسْتَبِقُ وَتَرَكْنَا يُوسُفَ عِندَ مَتَـٰعِنَا فَأَكَلَهُ ٱلذِّئْبُ ۖ وَمَآ أَنتَ بِمُؤْمِنٍ لَّنَا وَلَوْ كُنَّا صَـٰدِقِينَ","en":"They said, \"O our father, indeed we went racing each other and left Joseph with our possessions, and a wolf ate him. But you would not believe us, even if we were truthful.\"","tr":"Qaloo ya abanainna thahabna nastabiqu wataraknayoosufa AAinda mataAAina faakalahu aththi/buwama anta bimu/minin lana walaw kunna sadiqeen","juz":12,"page":237},{"s":12,"a":18,"key":"12:18","ar":"وَجَآءُو عَلَىٰ قَمِيصِهِۦ بِدَمٍ كَذِبٍ ۚ قَالَ بَلْ سَوَّلَتْ لَكُمْ أَنفُسُكُمْ أَمْرًا ۖ فَصَبْرٌ جَمِيلٌ ۖ وَٱللَّهُ ٱلْمُسْتَعَانُ عَلَىٰ مَا تَصِفُونَ","en":"And they brought upon his shirt false blood.1 [Jacob] said, \"Rather, your souls have enticed you to something, so patience is most fitting. And Allāh is the one sought for help against that which you describe.\"","tr":"Wajaoo AAala qameesihibidamin kathibin qala bal sawwalat lakum anfusukumamran fasabrun jameelun wallahu almustaAAanuAAala ma tasifoon","juz":12,"page":237},{"s":12,"a":19,"key":"12:19","ar":"وَجَآءَتْ سَيَّارَةٌ فَأَرْسَلُوا۟ وَارِدَهُمْ فَأَدْلَىٰ دَلْوَهُۥ ۖ قَالَ يَـٰبُشْرَىٰ هَـٰذَا غُلَـٰمٌ ۚ وَأَسَرُّوهُ بِضَـٰعَةً ۚ وَٱللَّهُ عَلِيمٌۢ بِمَا يَعْمَلُونَ","en":"And there came a company of travelers; then they sent their water drawer, and he let down his bucket. He said, \"Good news! Here is a boy.\" And they concealed him, [taking him] as merchandise;1 and Allāh was Knowing of what they did.","tr":"Wajaat sayyaratun faarsaloo waridahumfaadla dalwahu qala ya bushra hathaghulamun waasarroohu bidaAAatan wallahuAAaleemun bima yaAAmaloon","juz":12,"page":237},{"s":12,"a":20,"key":"12:20","ar":"وَشَرَوْهُ بِثَمَنٍۭ بَخْسٍ دَرَٰهِمَ مَعْدُودَةٍ وَكَانُوا۟ فِيهِ مِنَ ٱلزَّٰهِدِينَ","en":"And they sold him for a reduced price - a few dirhams - and they were, concerning him, of those content with little.","tr":"Washarawhu bithamanin bakhsin darahimamaAAdoodatin wakanoo feehi mina azzahideen","juz":12,"page":237},{"s":12,"a":21,"key":"12:21","ar":"وَقَالَ ٱلَّذِى ٱشْتَرَىٰهُ مِن مِّصْرَ لِٱمْرَأَتِهِۦٓ أَكْرِمِى مَثْوَىٰهُ عَسَىٰٓ أَن يَنفَعَنَآ أَوْ نَتَّخِذَهُۥ وَلَدًا ۚ وَكَذَٰلِكَ مَكَّنَّا لِيُوسُفَ فِى ٱلْأَرْضِ وَلِنُعَلِّمَهُۥ مِن تَأْوِيلِ ٱلْأَحَادِيثِ ۚ وَٱللَّهُ غَالِبٌ عَلَىٰٓ أَمْرِهِۦ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"And the one from Egypt1 who bought him said to his wife, \"Make his residence comfortable. Perhaps he will benefit us, or we will adopt him as a son.\" And thus, We established Joseph in the land that We might teach him the interpretation of events [i.e., dreams]. And Allāh is predominant over His affair, but most of the people do not know.","tr":"Waqala allathee ishtarahumin misra limraatihi akrimee mathwahu AAasaan yanfaAAana aw nattakhithahu waladan wakathalikamakkanna liyoosufa fee al-ardi walinuAAallimahu minta/weeli al-ahadeethi wallahu ghalibunAAala amrihi walakinna akthara annasila yaAAlamoon","juz":12,"page":237},{"s":12,"a":22,"key":"12:22","ar":"وَلَمَّا بَلَغَ أَشُدَّهُۥٓ ءَاتَيْنَـٰهُ حُكْمًا وَعِلْمًا ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ","en":"And when he [i.e., Joseph] reached maturity, We gave him judgement and knowledge. And thus We reward the doers of good.","tr":"Walamma balagha ashuddahu ataynahuhukman waAAilman wakathalika najzee almuhsineen","juz":12,"page":237},{"s":12,"a":23,"key":"12:23","ar":"وَرَٰوَدَتْهُ ٱلَّتِى هُوَ فِى بَيْتِهَا عَن نَّفْسِهِۦ وَغَلَّقَتِ ٱلْأَبْوَٰبَ وَقَالَتْ هَيْتَ لَكَ ۚ قَالَ مَعَاذَ ٱللَّهِ ۖ إِنَّهُۥ رَبِّىٓ أَحْسَنَ مَثْوَاىَ ۖ إِنَّهُۥ لَا يُفْلِحُ ٱلظَّـٰلِمُونَ","en":"And she, in whose house he was, sought to seduce him. She closed the doors and said, \"Come, you.\" He said, \"[I seek] the refuge of Allāh. Indeed, he1 is my master, who has made good my residence. Indeed, wrongdoers will not succeed.\"","tr":"Warawadat-hu allatee huwa fee baytihaAAan nafsihi waghallaqati al-abwaba waqalat haytalaka qala maAAatha Allahi innahu rabbee ahsanamathwaya innahu la yuflihu aththalimoon","juz":12,"page":238},{"s":12,"a":24,"key":"12:24","ar":"وَلَقَدْ هَمَّتْ بِهِۦ ۖ وَهَمَّ بِهَا لَوْلَآ أَن رَّءَا بُرْهَـٰنَ رَبِّهِۦ ۚ كَذَٰلِكَ لِنَصْرِفَ عَنْهُ ٱلسُّوٓءَ وَٱلْفَحْشَآءَ ۚ إِنَّهُۥ مِنْ عِبَادِنَا ٱلْمُخْلَصِينَ","en":"And she certainly determined [to seduce] him, and he would have inclined to her had he not seen the proof [i.e., sign] of his Lord. And thus [it was] that We should avert from him evil and immorality. Indeed, he was of Our chosen servants.","tr":"Walaqad hammat bihi wahamma biha lawlaan raa burhana rabbihi kathalika linasrifaAAanhu assoo-a walfahshaa innahumin AAibadina almukhlaseen","juz":12,"page":238},{"s":12,"a":25,"key":"12:25","ar":"وَٱسْتَبَقَا ٱلْبَابَ وَقَدَّتْ قَمِيصَهُۥ مِن دُبُرٍ وَأَلْفَيَا سَيِّدَهَا لَدَا ٱلْبَابِ ۚ قَالَتْ مَا جَزَآءُ مَنْ أَرَادَ بِأَهْلِكَ سُوٓءًا إِلَّآ أَن يُسْجَنَ أَوْ عَذَابٌ أَلِيمٌ","en":"And they both raced to the door, and she tore his shirt from the back, and they found her husband at the door. She said, \"What is the recompense of one who intended evil for your wife but that he be imprisoned or a painful punishment?\"","tr":"Wastabaqa albabawaqaddat qameesahu min duburin waalfaya sayyidahalada albabi qalat ma jazao manarada bi-ahlika soo-an illa an yusjana aw AAathabunaleem","juz":12,"page":238},{"s":12,"a":26,"key":"12:26","ar":"قَالَ هِىَ رَٰوَدَتْنِى عَن نَّفْسِى ۚ وَشَهِدَ شَاهِدٌ مِّنْ أَهْلِهَآ إِن كَانَ قَمِيصُهُۥ قُدَّ مِن قُبُلٍ فَصَدَقَتْ وَهُوَ مِنَ ٱلْكَـٰذِبِينَ","en":"[Joseph] said, \"It was she who sought to seduce me.\" And a witness from her family testified, \"If his shirt is torn from the front, then she has told the truth, and he is of the liars.","tr":"Qala hiya rawadatnee AAannafsee washahida shahidun min ahliha in kanaqameesuhu qudda min qubulin fasadaqat wahuwa minaalkathibeen","juz":12,"page":238},{"s":12,"a":27,"key":"12:27","ar":"وَإِن كَانَ قَمِيصُهُۥ قُدَّ مِن دُبُرٍ فَكَذَبَتْ وَهُوَ مِنَ ٱلصَّـٰدِقِينَ","en":"But if his shirt is torn from the back, then she has lied, and he is of the truthful.\"","tr":"Wa-in kana qameesuhu qudda minduburin fakathabat wahuwa mina assadiqeen","juz":12,"page":238},{"s":12,"a":28,"key":"12:28","ar":"فَلَمَّا رَءَا قَمِيصَهُۥ قُدَّ مِن دُبُرٍ قَالَ إِنَّهُۥ مِن كَيْدِكُنَّ ۖ إِنَّ كَيْدَكُنَّ عَظِيمٌ","en":"So when he [i.e., her husband] saw his shirt torn from the back, he said, \"Indeed, it is of your [i.e., women's] plan. Indeed, your plan is great [i.e., vehement].","tr":"Falamma raa qameesahuqudda min duburin qala innahu min kaydikunna innakaydakunna AAatheem","juz":12,"page":238},{"s":12,"a":29,"key":"12:29","ar":"يُوسُفُ أَعْرِضْ عَنْ هَـٰذَا ۚ وَٱسْتَغْفِرِى لِذَنۢبِكِ ۖ إِنَّكِ كُنتِ مِنَ ٱلْخَاطِـِٔينَ","en":"Joseph, ignore this.1 And, [my wife], ask forgiveness for your sin. Indeed, you were of the sinful.\"","tr":"Yoosufu aAArid AAan hatha wastaghfireelithanbiki innaki kunti mina alkhati-een","juz":12,"page":238},{"s":12,"a":30,"key":"12:30","ar":"۞ وَقَالَ نِسْوَةٌ فِى ٱلْمَدِينَةِ ٱمْرَأَتُ ٱلْعَزِيزِ تُرَٰوِدُ فَتَىٰهَا عَن نَّفْسِهِۦ ۖ قَدْ شَغَفَهَا حُبًّا ۖ إِنَّا لَنَرَىٰهَا فِى ضَلَـٰلٍ مُّبِينٍ","en":"And women in the city said, \"The wife of al-ʿAzeez is seeking to seduce her slave boy; he has impassioned her with love. Indeed, we see her [to be] in clear error.\"","tr":"Waqala niswatun fee almadeenatiimraatu alAAazeezi turawidu fataha AAannafsihi qad shaghafaha hubban inna lanarahafee dalalin mubeen","juz":12,"page":238},{"s":12,"a":31,"key":"12:31","ar":"فَلَمَّا سَمِعَتْ بِمَكْرِهِنَّ أَرْسَلَتْ إِلَيْهِنَّ وَأَعْتَدَتْ لَهُنَّ مُتَّكَـًٔا وَءَاتَتْ كُلَّ وَٰحِدَةٍ مِّنْهُنَّ سِكِّينًا وَقَالَتِ ٱخْرُجْ عَلَيْهِنَّ ۖ فَلَمَّا رَأَيْنَهُۥٓ أَكْبَرْنَهُۥ وَقَطَّعْنَ أَيْدِيَهُنَّ وَقُلْنَ حَـٰشَ لِلَّهِ مَا هَـٰذَا بَشَرًا إِنْ هَـٰذَآ إِلَّا مَلَكٌ كَرِيمٌ","en":"So when she heard of their scheming, she sent for them and prepared for them a banquet and gave each one of them a knife and said [to Joseph], \"Come out before them.\" And when they saw him, they greatly admired him and cut their hands1 and said, \"Perfect is Allāh!2 This is not a man; this is none but a noble angel.\"","tr":"Falamma samiAAat bimakrihinna arsalatilayhinna waaAAtadat lahunna muttakaan waatat kulla wahidatinminhunna sikkeenan waqalati okhruj AAalayhinna falammaraaynahu akbarnahu waqattaAAna aydiyahunna waqulna hashalillahi ma hatha basharan in hathailla malakun kareem","juz":12,"page":239},{"s":12,"a":32,"key":"12:32","ar":"قَالَتْ فَذَٰلِكُنَّ ٱلَّذِى لُمْتُنَّنِى فِيهِ ۖ وَلَقَدْ رَٰوَدتُّهُۥ عَن نَّفْسِهِۦ فَٱسْتَعْصَمَ ۖ وَلَئِن لَّمْ يَفْعَلْ مَآ ءَامُرُهُۥ لَيُسْجَنَنَّ وَلَيَكُونًا مِّنَ ٱلصَّـٰغِرِينَ","en":"She said, \"That is the one about whom you blamed me. And I certainly sought to seduce him, but he firmly refused; and if he will not do what I order him, he will surely be imprisoned and will be of those debased.\"","tr":"Qalat fathalikunna allatheelumtunnanee feehi walaqad rawadtuhu AAan nafsihi fastAAsamawala-in lam yafAAal ma amuruhu layusjanannawalayakoonan mina assaghireen","juz":12,"page":239},{"s":12,"a":33,"key":"12:33","ar":"قَالَ رَبِّ ٱلسِّجْنُ أَحَبُّ إِلَىَّ مِمَّا يَدْعُونَنِىٓ إِلَيْهِ ۖ وَإِلَّا تَصْرِفْ عَنِّى كَيْدَهُنَّ أَصْبُ إِلَيْهِنَّ وَأَكُن مِّنَ ٱلْجَـٰهِلِينَ","en":"He said, \"My Lord, prison is more to my liking than that to which they invite me. And if You do not avert from me their plan, I might incline toward them and [thus] be of the ignorant.\"","tr":"Qala rabbi assijnu ahabbuilayya mimma yadAAoonanee ilayhi wa-illa tasrifAAannee kaydahunna asbu ilayhinna waakun mina aljahileen","juz":12,"page":239},{"s":12,"a":34,"key":"12:34","ar":"فَٱسْتَجَابَ لَهُۥ رَبُّهُۥ فَصَرَفَ عَنْهُ كَيْدَهُنَّ ۚ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"So his Lord responded to him and averted from him their plan. Indeed, He is the Hearing, the Knowing.","tr":"Fastajaba lahu rabbuhu fasarafaAAanhu kaydahunna innahu huwa assameeAAu alAAaleem","juz":12,"page":239},{"s":12,"a":35,"key":"12:35","ar":"ثُمَّ بَدَا لَهُم مِّنۢ بَعْدِ مَا رَأَوُا۟ ٱلْـَٔايَـٰتِ لَيَسْجُنُنَّهُۥ حَتَّىٰ حِينٍ","en":"Then it appeared to them after they had seen the signs1 that he [i.e., al-ʿAzeez] should surely imprison him for a time.2","tr":"Thumma bada lahum min baAAdi maraawoo al-ayati layasjununnahu hatta heen","juz":12,"page":239},{"s":12,"a":36,"key":"12:36","ar":"وَدَخَلَ مَعَهُ ٱلسِّجْنَ فَتَيَانِ ۖ قَالَ أَحَدُهُمَآ إِنِّىٓ أَرَىٰنِىٓ أَعْصِرُ خَمْرًا ۖ وَقَالَ ٱلْـَٔاخَرُ إِنِّىٓ أَرَىٰنِىٓ أَحْمِلُ فَوْقَ رَأْسِى خُبْزًا تَأْكُلُ ٱلطَّيْرُ مِنْهُ ۖ نَبِّئْنَا بِتَأْوِيلِهِۦٓ ۖ إِنَّا نَرَىٰكَ مِنَ ٱلْمُحْسِنِينَ","en":"And there entered the prison with him two young men. One of them said, \"Indeed, I have seen myself [in a dream] pressing [grapes for] wine.\" The other said, \"Indeed, I have seen myself carrying upon my head [some] bread, from which the birds were eating. Inform us of its interpretation; indeed, we see you to be of those who do good.\"","tr":"Wadakhala maAAahu assijna fatayaniqala ahaduhuma innee aranee aAAsirukhamran waqala al-akharu innee aranee ahmilufawqa ra/see khubzan ta/kulu attayru minhu nabbi/nabita/weelihi inna naraka mina almuhsineen","juz":12,"page":239},{"s":12,"a":37,"key":"12:37","ar":"قَالَ لَا يَأْتِيكُمَا طَعَامٌ تُرْزَقَانِهِۦٓ إِلَّا نَبَّأْتُكُمَا بِتَأْوِيلِهِۦ قَبْلَ أَن يَأْتِيَكُمَا ۚ ذَٰلِكُمَا مِمَّا عَلَّمَنِى رَبِّىٓ ۚ إِنِّى تَرَكْتُ مِلَّةَ قَوْمٍ لَّا يُؤْمِنُونَ بِٱللَّهِ وَهُم بِٱلْـَٔاخِرَةِ هُمْ كَـٰفِرُونَ","en":"He said, \"You will not receive food that is provided to you except that I will inform you of its interpretation before it comes to you. That is from what my Lord has taught me. Indeed, I have left the religion of a people who do not believe in Allāh, and they, in the Hereafter, are disbelievers.","tr":"Qala la ya/teekuma taAAamunturzaqanihi illa nabba/tukuma bita/weelihiqabla an ya/tiyakuma thalikuma mimmaAAallamanee rabbee innee taraktu millata qawmin layu/minoona billahi wahum bil-akhiratihum kafiroon","juz":12,"page":239},{"s":12,"a":38,"key":"12:38","ar":"وَٱتَّبَعْتُ مِلَّةَ ءَابَآءِىٓ إِبْرَٰهِيمَ وَإِسْحَـٰقَ وَيَعْقُوبَ ۚ مَا كَانَ لَنَآ أَن نُّشْرِكَ بِٱللَّهِ مِن شَىْءٍ ۚ ذَٰلِكَ مِن فَضْلِ ٱللَّهِ عَلَيْنَا وَعَلَى ٱلنَّاسِ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَشْكُرُونَ","en":"And I have followed the religion of my fathers, Abraham, Isaac and Jacob. And it was not for us to associate anything with Allāh. That is from the favor of Allāh upon us and upon the people, but most of the people are not grateful.","tr":"WattabaAAtu millata aba-eeibraheema wa-ishaqa wayaAAqooba ma kanalana an nushrika billahi min shay-in thalikamin fadli Allahi AAalayna waAAala annasiwalakinna akthara annasi layashkuroon","juz":12,"page":240},{"s":12,"a":39,"key":"12:39","ar":"يَـٰصَـٰحِبَىِ ٱلسِّجْنِ ءَأَرْبَابٌ مُّتَفَرِّقُونَ خَيْرٌ أَمِ ٱللَّهُ ٱلْوَٰحِدُ ٱلْقَهَّارُ","en":"O [my] two companions of prison, are separate lords better or Allāh, the One,1 the Prevailing?2","tr":"Ya sahibayi assijniaarbabun mutafarriqoona khayrun ami Allahu alwahidualqahhar","juz":12,"page":240},{"s":12,"a":40,"key":"12:40","ar":"مَا تَعْبُدُونَ مِن دُونِهِۦٓ إِلَّآ أَسْمَآءً سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّآ أَنزَلَ ٱللَّهُ بِهَا مِن سُلْطَـٰنٍ ۚ إِنِ ٱلْحُكْمُ إِلَّا لِلَّهِ ۚ أَمَرَ أَلَّا تَعْبُدُوٓا۟ إِلَّآ إِيَّاهُ ۚ ذَٰلِكَ ٱلدِّينُ ٱلْقَيِّمُ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"You worship not besides Him except [mere] names you have named them,1 you and your fathers, for which Allāh has sent down no evidence. Legislation is not but for Allāh. He has commanded that you worship not except Him. That is the correct religion, but most of the people do not know.","tr":"Ma taAAbudoona min doonihi illaasmaan sammaytumooha antum waabaokumma anzala Allahu biha min sultaninini alhukmu illa lillahi amara allataAAbudoo illa iyyahu thalika addeenualqayyimu walakinna akthara annasi layaAAlamoon","juz":12,"page":240},{"s":12,"a":41,"key":"12:41","ar":"يَـٰصَـٰحِبَىِ ٱلسِّجْنِ أَمَّآ أَحَدُكُمَا فَيَسْقِى رَبَّهُۥ خَمْرًا ۖ وَأَمَّا ٱلْـَٔاخَرُ فَيُصْلَبُ فَتَأْكُلُ ٱلطَّيْرُ مِن رَّأْسِهِۦ ۚ قُضِىَ ٱلْأَمْرُ ٱلَّذِى فِيهِ تَسْتَفْتِيَانِ","en":"O two companions of prison, as for one of you, he will give drink to his master of wine; but as for the other, he will be crucified, and the birds will eat from his head. The matter has been decreed about which you both inquire.\"","tr":"Ya sahibayi assijniamma ahadukuma fayasqee rabbahu khamranwaamma al-akharu fayuslabu fata/kulu attayrumin ra/sihi qudiya al-amru allathee feehi tastaftiyan","juz":12,"page":240},{"s":12,"a":42,"key":"12:42","ar":"وَقَالَ لِلَّذِى ظَنَّ أَنَّهُۥ نَاجٍ مِّنْهُمَا ٱذْكُرْنِى عِندَ رَبِّكَ فَأَنسَىٰهُ ٱلشَّيْطَـٰنُ ذِكْرَ رَبِّهِۦ فَلَبِثَ فِى ٱلسِّجْنِ بِضْعَ سِنِينَ","en":"And he said to the one whom he knew would go free, \"Mention me before your master.\" But Satan made him forget the mention [to] his master, and he [i.e., Joseph] remained in prison several years.","tr":"Waqala lillathee thannaannahu najin minhuma othkurnee AAindarabbika faansahu ashshaytanu thikrarabbihi falabitha fee assijni bidAAa sineen","juz":12,"page":240},{"s":12,"a":43,"key":"12:43","ar":"وَقَالَ ٱلْمَلِكُ إِنِّىٓ أَرَىٰ سَبْعَ بَقَرَٰتٍ سِمَانٍ يَأْكُلُهُنَّ سَبْعٌ عِجَافٌ وَسَبْعَ سُنۢبُلَـٰتٍ خُضْرٍ وَأُخَرَ يَابِسَـٰتٍ ۖ يَـٰٓأَيُّهَا ٱلْمَلَأُ أَفْتُونِى فِى رُءْيَـٰىَ إِن كُنتُمْ لِلرُّءْيَا تَعْبُرُونَ","en":"And [subsequently] the king said, \"Indeed, I have seen [in a dream] seven fat cows being eaten by seven [that were] lean, and seven green spikes [of grain] and others [that were] dry. O eminent ones, explain to me my vision, if you should interpret visions.\"","tr":"Waqala almaliku innee arasabAAa baqaratin simanin ya/kuluhunna sabAAun AAijafunwasabAAa sunbulatin khudrin waokhara yabisatinya ayyuha almalao aftoonee fee ru/yaya inkuntum lirru/ya taAAburoon","juz":12,"page":240},{"s":12,"a":44,"key":"12:44","ar":"قَالُوٓا۟ أَضْغَـٰثُ أَحْلَـٰمٍ ۖ وَمَا نَحْنُ بِتَأْوِيلِ ٱلْأَحْلَـٰمِ بِعَـٰلِمِينَ","en":"They said, \"[It is but] a mixture of false dreams, and we are not learned in the interpretation of dreams.\"","tr":"Qaloo adghathu ahlaminwama nahnu bita/weeli al-ahlami biAAalimeen","juz":12,"page":241},{"s":12,"a":45,"key":"12:45","ar":"وَقَالَ ٱلَّذِى نَجَا مِنْهُمَا وَٱدَّكَرَ بَعْدَ أُمَّةٍ أَنَا۠ أُنَبِّئُكُم بِتَأْوِيلِهِۦ فَأَرْسِلُونِ","en":"But the one who was freed and remembered after a time said, \"I will inform you of its interpretation, so send me forth.\"","tr":"Waqala allathee najaminhuma waddakara baAAda ommatin anaonabbi-okum bita/weelihi faarsiloon","juz":12,"page":241},{"s":12,"a":46,"key":"12:46","ar":"يُوسُفُ أَيُّهَا ٱلصِّدِّيقُ أَفْتِنَا فِى سَبْعِ بَقَرَٰتٍ سِمَانٍ يَأْكُلُهُنَّ سَبْعٌ عِجَافٌ وَسَبْعِ سُنۢبُلَـٰتٍ خُضْرٍ وَأُخَرَ يَابِسَـٰتٍ لَّعَلِّىٓ أَرْجِعُ إِلَى ٱلنَّاسِ لَعَلَّهُمْ يَعْلَمُونَ","en":"[He said], \"Joseph, O man of truth, explain to us about seven fat cows eaten by seven [that were] lean, and seven green spikes [of grain] and others [that were] dry - that I may return to the people [i.e., the king and his court]; perhaps they will know [about you].\"","tr":"Yoosufu ayyuha assiddeequaftina fee sabAAi baqaratin simaninya/kuluhunna sabAAun AAijafun wasabAAi sunbulatinkhudrin waokhara yabisatin laAAallee arjiAAuila annasi laAAallahum yaAAlamoon","juz":12,"page":241},{"s":12,"a":47,"key":"12:47","ar":"قَالَ تَزْرَعُونَ سَبْعَ سِنِينَ دَأَبًا فَمَا حَصَدتُّمْ فَذَرُوهُ فِى سُنۢبُلِهِۦٓ إِلَّا قَلِيلًا مِّمَّا تَأْكُلُونَ","en":"[Joseph] said, \"You will plant for seven years consecutively; and what you harvest leave in its spikes, except a little from which you will eat.","tr":"Qala tazraAAoona sabAAa sineenadaaban fama hasadtum fatharoohu feesunbulihi illa qaleelan mimma ta/kuloon","juz":12,"page":241},{"s":12,"a":48,"key":"12:48","ar":"ثُمَّ يَأْتِى مِنۢ بَعْدِ ذَٰلِكَ سَبْعٌ شِدَادٌ يَأْكُلْنَ مَا قَدَّمْتُمْ لَهُنَّ إِلَّا قَلِيلًا مِّمَّا تُحْصِنُونَ","en":"Then will come after that seven difficult [years] which will consume what you advanced [i.e., saved] for them, except a little from which you will store.","tr":"Thumma ya/tee min baAAdi thalikasabAAun shidadun ya/kulna ma qaddamtum lahunna illaqaleelan mimma tuhsinoon","juz":12,"page":241},{"s":12,"a":49,"key":"12:49","ar":"ثُمَّ يَأْتِى مِنۢ بَعْدِ ذَٰلِكَ عَامٌ فِيهِ يُغَاثُ ٱلنَّاسُ وَفِيهِ يَعْصِرُونَ","en":"Then will come after that a year in which the people will be given rain and in which they will press [olives and grapes].\"","tr":"Thumma ya/tee min baAAdi thalika AAamunfeehi yughathu annasu wafeehi yaAAsiroon","juz":12,"page":241},{"s":12,"a":50,"key":"12:50","ar":"وَقَالَ ٱلْمَلِكُ ٱئْتُونِى بِهِۦ ۖ فَلَمَّا جَآءَهُ ٱلرَّسُولُ قَالَ ٱرْجِعْ إِلَىٰ رَبِّكَ فَسْـَٔلْهُ مَا بَالُ ٱلنِّسْوَةِ ٱلَّـٰتِى قَطَّعْنَ أَيْدِيَهُنَّ ۚ إِنَّ رَبِّى بِكَيْدِهِنَّ عَلِيمٌ","en":"And the king said, \"Bring him to me.\" But when the messenger came to him, [Joseph] said, \"Return to your master and ask him what is the case of the women who cut their hands. Indeed, my Lord is Knowing of their plan.\"","tr":"Waqala almaliku i/toonee bihi falammajaahu arrasoolu qala irjiAA ilarabbika fas-alhu ma balu anniswatiallatee qattaAAna aydiyahunna inna rabbeebikaydihinna AAaleem","juz":12,"page":241},{"s":12,"a":51,"key":"12:51","ar":"قَالَ مَا خَطْبُكُنَّ إِذْ رَٰوَدتُّنَّ يُوسُفَ عَن نَّفْسِهِۦ ۚ قُلْنَ حَـٰشَ لِلَّهِ مَا عَلِمْنَا عَلَيْهِ مِن سُوٓءٍ ۚ قَالَتِ ٱمْرَأَتُ ٱلْعَزِيزِ ٱلْـَٔـٰنَ حَصْحَصَ ٱلْحَقُّ أَنَا۠ رَٰوَدتُّهُۥ عَن نَّفْسِهِۦ وَإِنَّهُۥ لَمِنَ ٱلصَّـٰدِقِينَ","en":"Said [the king to the women], \"What was your condition when you sought to seduce Joseph?\" They said, \"Perfect is Allāh!1 We know about him no evil.\" The wife of al-ʿAzeez said, \"Now the truth has become evident. It was I who sought to seduce him, and indeed, he is of the truthful.","tr":"Qala ma khatbukunna ithrawadtunna yoosufa AAan nafsihi qulna hasha lillahima AAalimna AAalayhi min soo-in qalatiimraatu alAAazeezi al-ana hashasa alhaqquana rawadtuhu AAan nafsihi wa-innahu lamina assadiqeen","juz":12,"page":241},{"s":12,"a":52,"key":"12:52","ar":"ذَٰلِكَ لِيَعْلَمَ أَنِّى لَمْ أَخُنْهُ بِٱلْغَيْبِ وَأَنَّ ٱللَّهَ لَا يَهْدِى كَيْدَ ٱلْخَآئِنِينَ","en":"That is so he [i.e., al-ʿAzeez] will know that I did not betray him in [his] absence and that Allāh does not guide the plan of betrayers.","tr":"Thalika liyaAAlama annee lam akhunhubilghaybi waanna Allaha la yahdee kaydaalkha-ineen","juz":12,"page":241},{"s":12,"a":53,"key":"12:53","ar":"۞ وَمَآ أُبَرِّئُ نَفْسِىٓ ۚ إِنَّ ٱلنَّفْسَ لَأَمَّارَةٌۢ بِٱلسُّوٓءِ إِلَّا مَا رَحِمَ رَبِّىٓ ۚ إِنَّ رَبِّى غَفُورٌ رَّحِيمٌ","en":"And I do not acquit myself. Indeed, the soul is a persistent enjoiner of evil, except those upon which my Lord has mercy. Indeed, my Lord is Forgiving and Merciful.\"1","tr":"Wama obarri-o nafsee inna annafsalaammaratun bissoo-i illa ma rahimarabbee inna rabbee ghafoorun raheem","juz":13,"page":242},{"s":12,"a":54,"key":"12:54","ar":"وَقَالَ ٱلْمَلِكُ ٱئْتُونِى بِهِۦٓ أَسْتَخْلِصْهُ لِنَفْسِى ۖ فَلَمَّا كَلَّمَهُۥ قَالَ إِنَّكَ ٱلْيَوْمَ لَدَيْنَا مَكِينٌ أَمِينٌ","en":"And the king said, \"Bring him to me; I will appoint him exclusively for myself.\" And when he spoke to him, he said, \"Indeed, you are today established [in position] and trusted.\"","tr":"Waqala almaliku i/toonee bihiastakhlishu linafsee falamma kallamahu qalainnaka alyawma ladayna makeenun ameen","juz":13,"page":242},{"s":12,"a":55,"key":"12:55","ar":"قَالَ ٱجْعَلْنِى عَلَىٰ خَزَآئِنِ ٱلْأَرْضِ ۖ إِنِّى حَفِيظٌ عَلِيمٌ","en":"[Joseph] said, \"Appoint me over the storehouses of the land. Indeed, I will be a knowing guardian.\"","tr":"Qala ijAAalnee AAala khaza-inial-ardi innee hafeethun AAaleem","juz":13,"page":242},{"s":12,"a":56,"key":"12:56","ar":"وَكَذَٰلِكَ مَكَّنَّا لِيُوسُفَ فِى ٱلْأَرْضِ يَتَبَوَّأُ مِنْهَا حَيْثُ يَشَآءُ ۚ نُصِيبُ بِرَحْمَتِنَا مَن نَّشَآءُ ۖ وَلَا نُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ","en":"And thus We established Joseph in the land to settle therein wherever he willed. We touch with Our mercy whom We will, and We do not allow to be lost the reward of those who do good.","tr":"Wakathalika makanna liyoosufafee al-ardi yatabawwao minha haythu yashaonuseebu birahmatina man nashao walanudeeAAu ajra almuhsineen","juz":13,"page":242},{"s":12,"a":57,"key":"12:57","ar":"وَلَأَجْرُ ٱلْـَٔاخِرَةِ خَيْرٌ لِّلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ","en":"And the reward of the Hereafter is better for those who believed and were fearing Allāh.","tr":"Walaajru al-akhirati khayrun lillatheenaamanoo wakanoo yattaqoon","juz":13,"page":242},{"s":12,"a":58,"key":"12:58","ar":"وَجَآءَ إِخْوَةُ يُوسُفَ فَدَخَلُوا۟ عَلَيْهِ فَعَرَفَهُمْ وَهُمْ لَهُۥ مُنكِرُونَ","en":"And the brothers of Joseph came [seeking food], and they entered upon him; and he recognized them, but he was to them unknown.1","tr":"Wajaa ikhwatu yoosufa fadakhalooAAalayhi faAAarafahum wahum lahu munkiroon","juz":13,"page":242},{"s":12,"a":59,"key":"12:59","ar":"وَلَمَّا جَهَّزَهُم بِجَهَازِهِمْ قَالَ ٱئْتُونِى بِأَخٍ لَّكُم مِّنْ أَبِيكُمْ ۚ أَلَا تَرَوْنَ أَنِّىٓ أُوفِى ٱلْكَيْلَ وَأَنَا۠ خَيْرُ ٱلْمُنزِلِينَ","en":"And when he had furnished them with their supplies, he said, \"Bring me a brother of yours from your father.1 Do you not see that I give full measure and that I am the best of accommodators?","tr":"Walamma jahhazahum bijahazihimqala i/toonee bi-akhin lakum min abeekum alatarawna annee oofee alkayla waana khayru almunzileen","juz":13,"page":242},{"s":12,"a":60,"key":"12:60","ar":"فَإِن لَّمْ تَأْتُونِى بِهِۦ فَلَا كَيْلَ لَكُمْ عِندِى وَلَا تَقْرَبُونِ","en":"But if you do not bring him to me, no measure will there be [hereafter] for you from me, nor will you approach me.\"","tr":"Fa-in lam ta/toonee bihi fala kaylalakum AAindee wala taqraboon","juz":13,"page":242},{"s":12,"a":61,"key":"12:61","ar":"قَالُوا۟ سَنُرَٰوِدُ عَنْهُ أَبَاهُ وَإِنَّا لَفَـٰعِلُونَ","en":"They said, \"We will attempt to dissuade his father from [keeping] him, and indeed, we will do [it].\"","tr":"Qaloo sanurawidu AAanhu abahuwa-inna lafaAAiloon","juz":13,"page":242},{"s":12,"a":62,"key":"12:62","ar":"وَقَالَ لِفِتْيَـٰنِهِ ٱجْعَلُوا۟ بِضَـٰعَتَهُمْ فِى رِحَالِهِمْ لَعَلَّهُمْ يَعْرِفُونَهَآ إِذَا ٱنقَلَبُوٓا۟ إِلَىٰٓ أَهْلِهِمْ لَعَلَّهُمْ يَرْجِعُونَ","en":"And [Joseph] said to his servants, \"Put their merchandise1 into their saddlebags so they might recognize it when they have gone back to their people that perhaps they will [again] return.\"","tr":"Waqala lifityanihi ijAAaloo bidaAAatahumfee rihalihim laAAallahum yaAArifoonaha ithainqalaboo ila ahlihim laAAallahum yarjiAAoon","juz":13,"page":242},{"s":12,"a":63,"key":"12:63","ar":"فَلَمَّا رَجَعُوٓا۟ إِلَىٰٓ أَبِيهِمْ قَالُوا۟ يَـٰٓأَبَانَا مُنِعَ مِنَّا ٱلْكَيْلُ فَأَرْسِلْ مَعَنَآ أَخَانَا نَكْتَلْ وَإِنَّا لَهُۥ لَحَـٰفِظُونَ","en":"So when they returned to their father, they said, \"O our father, [further] measure has been denied to us, so send with us our brother [that] we will be given measure. And indeed, we will be his guardians.\"","tr":"Falamma rajaAAoo ila abeehim qalooya abana muniAAa minna alkaylufaarsil maAAana akhana naktal wa-innalahu lahafithoon","juz":13,"page":242},{"s":12,"a":64,"key":"12:64","ar":"قَالَ هَلْ ءَامَنُكُمْ عَلَيْهِ إِلَّا كَمَآ أَمِنتُكُمْ عَلَىٰٓ أَخِيهِ مِن قَبْلُ ۖ فَٱللَّهُ خَيْرٌ حَـٰفِظًا ۖ وَهُوَ أَرْحَمُ ٱلرَّٰحِمِينَ","en":"He said, \"Should I entrust you with him except [under coercion] as I entrusted you with his brother before? But Allāh is the best guardian, and He is the most merciful of the merciful.\"","tr":"Qala hal amanukum AAalayhi illakama amintukum AAala akheehi min qablu fallahukhayrun hafithan wahuwa arhamu arrahimeen","juz":13,"page":243},{"s":12,"a":65,"key":"12:65","ar":"وَلَمَّا فَتَحُوا۟ مَتَـٰعَهُمْ وَجَدُوا۟ بِضَـٰعَتَهُمْ رُدَّتْ إِلَيْهِمْ ۖ قَالُوا۟ يَـٰٓأَبَانَا مَا نَبْغِى ۖ هَـٰذِهِۦ بِضَـٰعَتُنَا رُدَّتْ إِلَيْنَا ۖ وَنَمِيرُ أَهْلَنَا وَنَحْفَظُ أَخَانَا وَنَزْدَادُ كَيْلَ بَعِيرٍ ۖ ذَٰلِكَ كَيْلٌ يَسِيرٌ","en":"And when they opened their baggage, they found their merchandise returned to them. They said, \"O our father, what [more] could we desire? This is our merchandise returned to us. And we will obtain supplies [i.e., food] for our family and protect our brother and obtain an increase of a camel's load; that is an easy measurement.\"1","tr":"Walamma fatahoo mataAAahumwajadoo bidaAAatahum ruddat ilayhim qaloo yaabana ma nabghee hathihi bidaAAatunaruddat ilayna wanameeru ahlana wanahfathuakhana wanazdadu kayla baAAeerin thalikakaylun yaseer","juz":13,"page":243},{"s":12,"a":66,"key":"12:66","ar":"قَالَ لَنْ أُرْسِلَهُۥ مَعَكُمْ حَتَّىٰ تُؤْتُونِ مَوْثِقًا مِّنَ ٱللَّهِ لَتَأْتُنَّنِى بِهِۦٓ إِلَّآ أَن يُحَاطَ بِكُمْ ۖ فَلَمَّآ ءَاتَوْهُ مَوْثِقَهُمْ قَالَ ٱللَّهُ عَلَىٰ مَا نَقُولُ وَكِيلٌ","en":"[Jacob] said, \"Never will I send him with you until you give me a promise [i.e., oath] by Allāh that you will bring him [back] to me, unless you should be surrounded [i.e., overcome by enemies].\" And when they had given their promise, he said, \"Allāh, over what we say, is Entrusted.\"1","tr":"Qala lan orsilahu maAAakum hattatu/tooni mawthiqan mina Allahi lata/tunnanee bihi illaan yuhata bikum falamma atawhu mawthiqahum qalaAllahu AAala ma naqoolu wakeel","juz":13,"page":243},{"s":12,"a":67,"key":"12:67","ar":"وَقَالَ يَـٰبَنِىَّ لَا تَدْخُلُوا۟ مِنۢ بَابٍ وَٰحِدٍ وَٱدْخُلُوا۟ مِنْ أَبْوَٰبٍ مُّتَفَرِّقَةٍ ۖ وَمَآ أُغْنِى عَنكُم مِّنَ ٱللَّهِ مِن شَىْءٍ ۖ إِنِ ٱلْحُكْمُ إِلَّا لِلَّهِ ۖ عَلَيْهِ تَوَكَّلْتُ ۖ وَعَلَيْهِ فَلْيَتَوَكَّلِ ٱلْمُتَوَكِّلُونَ","en":"And he said, \"O my sons, do not enter from one gate but enter from different gates; and I cannot avail you against [the decree of] Allāh at all. The decision is only for Allāh; upon Him I have relied, and upon Him let those who would rely [indeed] rely.\"","tr":"Waqala ya baniyya latadkhuloo min babin wahidin wadkhuloo minabwabin mutafarriqatin wama oghnee AAankum mina Allahimin shay-in ini alhukmu illa lillahiAAalayhi tawakkaltu waAAalayhi falyatawakkali almutawakkiloon","juz":13,"page":243},{"s":12,"a":68,"key":"12:68","ar":"وَلَمَّا دَخَلُوا۟ مِنْ حَيْثُ أَمَرَهُمْ أَبُوهُم مَّا كَانَ يُغْنِى عَنْهُم مِّنَ ٱللَّهِ مِن شَىْءٍ إِلَّا حَاجَةً فِى نَفْسِ يَعْقُوبَ قَضَىٰهَا ۚ وَإِنَّهُۥ لَذُو عِلْمٍ لِّمَا عَلَّمْنَـٰهُ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"And when they entered from where their father had ordered them, it did not avail them against Allāh at all except [it was] a need [i.e., concern] within the soul of Jacob, which he satisfied. And indeed, he was a possessor of knowledge because of what We had taught him, but most of the people do not know.","tr":"Walamma dakhaloo min haythuamarahum aboohum ma kana yughnee AAanhum mina Allahimin shay-in illa hajatan fee nafsi yaAAqooba qadahawa-innahu lathoo AAilmin lima AAallamnahuwalakinna akthara annasi layaAAlamoon","juz":13,"page":243},{"s":12,"a":69,"key":"12:69","ar":"وَلَمَّا دَخَلُوا۟ عَلَىٰ يُوسُفَ ءَاوَىٰٓ إِلَيْهِ أَخَاهُ ۖ قَالَ إِنِّىٓ أَنَا۠ أَخُوكَ فَلَا تَبْتَئِسْ بِمَا كَانُوا۟ يَعْمَلُونَ","en":"And when they entered upon Joseph, he took his brother to himself; he said, \"Indeed, I am your brother, so do not despair over what they used to do [to me].\"","tr":"Walamma dakhaloo AAala yoosufaawa ilayhi akhahu qala innee anaakhooka fala tabta-is bima kanoo yaAAmaloon","juz":13,"page":243},{"s":12,"a":70,"key":"12:70","ar":"فَلَمَّا جَهَّزَهُم بِجَهَازِهِمْ جَعَلَ ٱلسِّقَايَةَ فِى رَحْلِ أَخِيهِ ثُمَّ أَذَّنَ مُؤَذِّنٌ أَيَّتُهَا ٱلْعِيرُ إِنَّكُمْ لَسَـٰرِقُونَ","en":"So when he had furnished them with their supplies, he put the [gold measuring] bowl into the bag of his brother. Then an announcer called out, \"O caravan, indeed you are thieves.\"","tr":"Falamma jahhazahum bijahazihimjaAAala assiqayata fee rahli akheehi thummaaththana mu-aththinun ayyatuha alAAeeruinnakum lasariqoon","juz":13,"page":244},{"s":12,"a":71,"key":"12:71","ar":"قَالُوا۟ وَأَقْبَلُوا۟ عَلَيْهِم مَّاذَا تَفْقِدُونَ","en":"They said while approaching them, \"What is it you are missing?\"","tr":"Qaloo waaqbaloo AAalayhim mathatafqidoon","juz":13,"page":244},{"s":12,"a":72,"key":"12:72","ar":"قَالُوا۟ نَفْقِدُ صُوَاعَ ٱلْمَلِكِ وَلِمَن جَآءَ بِهِۦ حِمْلُ بَعِيرٍ وَأَنَا۠ بِهِۦ زَعِيمٌ","en":"They said, \"We are missing the measure of the king. And for he who produces it is [the reward of] a camel's load, and I am responsible for it.\"","tr":"Qaloo nafqidu suwaAAaalmaliki waliman jaa bihi himlu baAAeerin waanabihi zaAAeem","juz":13,"page":244},{"s":12,"a":73,"key":"12:73","ar":"قَالُوا۟ تَٱللَّهِ لَقَدْ عَلِمْتُم مَّا جِئْنَا لِنُفْسِدَ فِى ٱلْأَرْضِ وَمَا كُنَّا سَـٰرِقِينَ","en":"They said, \"By Allāh, you have certainly known that we did not come to cause corruption in the land, and we have not been thieves.\"","tr":"Qaloo tallahi laqadAAalimtum ma ji/na linufsida fee al-ardi wamakunna sariqeen","juz":13,"page":244},{"s":12,"a":74,"key":"12:74","ar":"قَالُوا۟ فَمَا جَزَٰٓؤُهُۥٓ إِن كُنتُمْ كَـٰذِبِينَ","en":"They [the accusers] said, \"Then what would be its recompense1 if you should be liars?\"","tr":"Qaloo fama jazaohu inkuntum kathibeen","juz":13,"page":244},{"s":12,"a":75,"key":"12:75","ar":"قَالُوا۟ جَزَٰٓؤُهُۥ مَن وُجِدَ فِى رَحْلِهِۦ فَهُوَ جَزَٰٓؤُهُۥ ۚ كَذَٰلِكَ نَجْزِى ٱلظَّـٰلِمِينَ","en":"[The brothers] said, \"Its recompense is that he in whose bag it is found - he [himself] will be its recompense.1 Thus do we recompense the wrongdoers.\"","tr":"Qaloo jazaohu man wujida feerahlihi fahuwa jazaohu kathalika najzee aththalimeen","juz":13,"page":244},{"s":12,"a":76,"key":"12:76","ar":"فَبَدَأَ بِأَوْعِيَتِهِمْ قَبْلَ وِعَآءِ أَخِيهِ ثُمَّ ٱسْتَخْرَجَهَا مِن وِعَآءِ أَخِيهِ ۚ كَذَٰلِكَ كِدْنَا لِيُوسُفَ ۖ مَا كَانَ لِيَأْخُذَ أَخَاهُ فِى دِينِ ٱلْمَلِكِ إِلَّآ أَن يَشَآءَ ٱللَّهُ ۚ نَرْفَعُ دَرَجَـٰتٍ مَّن نَّشَآءُ ۗ وَفَوْقَ كُلِّ ذِى عِلْمٍ عَلِيمٌ","en":"So he began [the search] with their bags before the bag of his brother; then he extracted it from the bag of his brother. Thus did We plan for Joseph. He could not have taken his brother within the religion [i.e., law] of the king except that Allāh willed. We raise in degrees whom We will, but over every possessor of knowledge is one [more] knowing.1","tr":"Fabadaa bi-awAAiyatihim qabla wiAAa-iakheehi thumma istakhrajaha min wiAAa-i akheehi kathalikakidna liyoosufa ma kana liya/khuthaakhahu fee deeni almaliki illa an yashaa AllahunarfaAAu darajatin man nashao wafawqa kulli theeAAilmin AAaleem","juz":13,"page":244},{"s":12,"a":77,"key":"12:77","ar":"۞ قَالُوٓا۟ إِن يَسْرِقْ فَقَدْ سَرَقَ أَخٌ لَّهُۥ مِن قَبْلُ ۚ فَأَسَرَّهَا يُوسُفُ فِى نَفْسِهِۦ وَلَمْ يُبْدِهَا لَهُمْ ۚ قَالَ أَنتُمْ شَرٌّ مَّكَانًا ۖ وَٱللَّهُ أَعْلَمُ بِمَا تَصِفُونَ","en":"They said, \"If he steals - a brother of his has stolen before.\" But Joseph kept it within himself and did not reveal it to them.1 He said, \"You are worse in position, and Allāh is most knowing of what you describe.\"","tr":"Qaloo in yasriq faqad saraqa akhunlahu min qablu faasarraha yoosufu fee nafsihi walam yubdihalahum qala antum sharrun makanan wallahuaAAlamu bima tasifoon","juz":13,"page":244},{"s":12,"a":78,"key":"12:78","ar":"قَالُوا۟ يَـٰٓأَيُّهَا ٱلْعَزِيزُ إِنَّ لَهُۥٓ أَبًا شَيْخًا كَبِيرًا فَخُذْ أَحَدَنَا مَكَانَهُۥٓ ۖ إِنَّا نَرَىٰكَ مِنَ ٱلْمُحْسِنِينَ","en":"They said, \"O ʿAzeez,1 indeed he has a father [who is] an old man, so take one of us in place of him. Indeed, we see you as a doer of good.\"","tr":"Qaloo ya ayyuhaalAAazeezu inna lahu aban shaykhan kabeeran fakhuth ahadanamakanahu inna naraka mina almuhsineen","juz":13,"page":244},{"s":12,"a":79,"key":"12:79","ar":"قَالَ مَعَاذَ ٱللَّهِ أَن نَّأْخُذَ إِلَّا مَن وَجَدْنَا مَتَـٰعَنَا عِندَهُۥٓ إِنَّآ إِذًا لَّظَـٰلِمُونَ","en":"He said, \"[I seek] the refuge of Allāh [to prevent] that we take except him with whom we found our possession. Indeed, we would then be unjust.\"","tr":"Qala maAAatha Allahi anna/khutha illa man wajadna mataAAanaAAindahu inna ithan lathalimoon","juz":13,"page":245},{"s":12,"a":80,"key":"12:80","ar":"فَلَمَّا ٱسْتَيْـَٔسُوا۟ مِنْهُ خَلَصُوا۟ نَجِيًّا ۖ قَالَ كَبِيرُهُمْ أَلَمْ تَعْلَمُوٓا۟ أَنَّ أَبَاكُمْ قَدْ أَخَذَ عَلَيْكُم مَّوْثِقًا مِّنَ ٱللَّهِ وَمِن قَبْلُ مَا فَرَّطتُمْ فِى يُوسُفَ ۖ فَلَنْ أَبْرَحَ ٱلْأَرْضَ حَتَّىٰ يَأْذَنَ لِىٓ أَبِىٓ أَوْ يَحْكُمَ ٱللَّهُ لِى ۖ وَهُوَ خَيْرُ ٱلْحَـٰكِمِينَ","en":"So when they had despaired of him, they secluded themselves in private consultation. The eldest of them said, \"Do you not know that your father has taken upon you an oath by Allāh and [that] before you failed in [your duty to] Joseph? So I will never leave [this] land until my father permits me or Allāh decides for me,1 and He is the best of judges.","tr":"Falamma istay-asoo minhu khalasoonajiyyan qala kabeeruhum alam taAAlamoo anna abakumqad akhatha AAalaykum mawthiqan mina Allahi waminqablu ma farrattum fee yoosufa falan abrahaal-arda hatta ya/thana lee abee aw yahkumaAllahu lee wahuwa khayru alhakimeen","juz":13,"page":245},{"s":12,"a":81,"key":"12:81","ar":"ٱرْجِعُوٓا۟ إِلَىٰٓ أَبِيكُمْ فَقُولُوا۟ يَـٰٓأَبَانَآ إِنَّ ٱبْنَكَ سَرَقَ وَمَا شَهِدْنَآ إِلَّا بِمَا عَلِمْنَا وَمَا كُنَّا لِلْغَيْبِ حَـٰفِظِينَ","en":"Return to your father and say, 'O our father, indeed your son has stolen, and we did not testify except to what we knew. And we were not witnesses of the unseen.1","tr":"IrjiAAoo ila abeekum faqooloo yaabana inna ibnaka saraqa wama shahidnailla bima AAalimna wama kunnalilghaybi hafitheen","juz":13,"page":245},{"s":12,"a":82,"key":"12:82","ar":"وَسْـَٔلِ ٱلْقَرْيَةَ ٱلَّتِى كُنَّا فِيهَا وَٱلْعِيرَ ٱلَّتِىٓ أَقْبَلْنَا فِيهَا ۖ وَإِنَّا لَصَـٰدِقُونَ","en":"And ask the city in which we were and the caravan in which we came - and indeed, we are truthful.'\"","tr":"Was-ali alqaryata allatee kunnafeeha walAAeera allatee aqbalna feehawa-inna lasadiqoon","juz":13,"page":245},{"s":12,"a":83,"key":"12:83","ar":"قَالَ بَلْ سَوَّلَتْ لَكُمْ أَنفُسُكُمْ أَمْرًا ۖ فَصَبْرٌ جَمِيلٌ ۖ عَسَى ٱللَّهُ أَن يَأْتِيَنِى بِهِمْ جَمِيعًا ۚ إِنَّهُۥ هُوَ ٱلْعَلِيمُ ٱلْحَكِيمُ","en":"[Jacob] said, \"Rather, your souls have enticed you to something, so patience is most fitting. Perhaps Allāh will bring them to me all together. Indeed, it is He who is the Knowing, the Wise.\"","tr":"Qala bal sawwalat lakum anfusukumamran fasabrun jameelun AAasa Allahu anya/tiyanee bihim jameeAAan innahu huwa alAAaleemu alhakeem","juz":13,"page":245},{"s":12,"a":84,"key":"12:84","ar":"وَتَوَلَّىٰ عَنْهُمْ وَقَالَ يَـٰٓأَسَفَىٰ عَلَىٰ يُوسُفَ وَٱبْيَضَّتْ عَيْنَاهُ مِنَ ٱلْحُزْنِ فَهُوَ كَظِيمٌ","en":"And he turned away from them and said, \"Oh, my sorrow over Joseph,\" and his eyes became white1 from grief, for he was [of that] a suppressor.2","tr":"Watawalla AAanhum waqala yaasafa AAala yoosufa wabyaddat AAaynahumina alhuzni fahuwa katheem","juz":13,"page":245},{"s":12,"a":85,"key":"12:85","ar":"قَالُوا۟ تَٱللَّهِ تَفْتَؤُا۟ تَذْكُرُ يُوسُفَ حَتَّىٰ تَكُونَ حَرَضًا أَوْ تَكُونَ مِنَ ٱلْهَـٰلِكِينَ","en":"They said, \"By Allāh, you will not cease remembering Joseph until you become fatally ill or become of those who perish.\"","tr":"Qaloo tallahi taftaotathkuru yoosufa hatta takoona haradanaw takoona mina alhalikeen","juz":13,"page":245},{"s":12,"a":86,"key":"12:86","ar":"قَالَ إِنَّمَآ أَشْكُوا۟ بَثِّى وَحُزْنِىٓ إِلَى ٱللَّهِ وَأَعْلَمُ مِنَ ٱللَّهِ مَا لَا تَعْلَمُونَ","en":"He said, \"I only complain of my suffering and my grief to Allāh, and I know from Allāh that which you do not know.","tr":"Qala innama ashkoo baththee wahuzneeila Allahi waaAAlamu mina Allahi ma lataAAlamoon","juz":13,"page":245},{"s":12,"a":87,"key":"12:87","ar":"يَـٰبَنِىَّ ٱذْهَبُوا۟ فَتَحَسَّسُوا۟ مِن يُوسُفَ وَأَخِيهِ وَلَا تَا۟يْـَٔسُوا۟ مِن رَّوْحِ ٱللَّهِ ۖ إِنَّهُۥ لَا يَا۟يْـَٔسُ مِن رَّوْحِ ٱللَّهِ إِلَّا ٱلْقَوْمُ ٱلْكَـٰفِرُونَ","en":"O my sons, go and find out about Joseph and his brother and despair not of relief from Allāh. Indeed, no one despairs of relief from Allāh except the disbelieving people.\"","tr":"Ya baniyya ithhaboo fatahassasoomin yoosufa waakheehi wala tay-asoo min rawhi Allahiinnahu la yay-asu min rawhi Allahi illaalqawmu alkafiroon","juz":13,"page":246},{"s":12,"a":88,"key":"12:88","ar":"فَلَمَّا دَخَلُوا۟ عَلَيْهِ قَالُوا۟ يَـٰٓأَيُّهَا ٱلْعَزِيزُ مَسَّنَا وَأَهْلَنَا ٱلضُّرُّ وَجِئْنَا بِبِضَـٰعَةٍ مُّزْجَىٰةٍ فَأَوْفِ لَنَا ٱلْكَيْلَ وَتَصَدَّقْ عَلَيْنَآ ۖ إِنَّ ٱللَّهَ يَجْزِى ٱلْمُتَصَدِّقِينَ","en":"So when they entered upon him [i.e., Joseph], they said, \"O ʿAzeez, adversity has touched us and our family, and we have come with goods poor in quality, but give us full measure and be charitable to us. Indeed, Allāh rewards the charitable.\"","tr":"Falamma dakhaloo AAalayhi qalooya ayyuha alAAazeezu massana waahlanaaddurru waji/na bibidaAAatin muzjatinfaawfi lana alkayla watasaddaq AAalayna innaAllaha yajzee almutasaddiqeen","juz":13,"page":246},{"s":12,"a":89,"key":"12:89","ar":"قَالَ هَلْ عَلِمْتُم مَّا فَعَلْتُم بِيُوسُفَ وَأَخِيهِ إِذْ أَنتُمْ جَـٰهِلُونَ","en":"He said, \"Do you know what you did with Joseph and his brother when you were ignorant?\"","tr":"Qala hal AAalimtum mafaAAaltum biyoosufa waakheehi ith antum jahiloon","juz":13,"page":246},{"s":12,"a":90,"key":"12:90","ar":"قَالُوٓا۟ أَءِنَّكَ لَأَنتَ يُوسُفُ ۖ قَالَ أَنَا۠ يُوسُفُ وَهَـٰذَآ أَخِى ۖ قَدْ مَنَّ ٱللَّهُ عَلَيْنَآ ۖ إِنَّهُۥ مَن يَتَّقِ وَيَصْبِرْ فَإِنَّ ٱللَّهَ لَا يُضِيعُ أَجْرَ ٱلْمُحْسِنِينَ","en":"They said, \"Are you indeed Joseph?\" He said, \"I am Joseph, and this is my brother. Allāh has certainly favored us. Indeed, he who fears Allāh and is patient, then indeed, Allāh does not allow to be lost the reward of those who do good.\"","tr":"Qaloo a-innaka laanta yoosufa qalaana yoosufu wahatha akhee qad manna AllahuAAalayna innahu man yattaqi wayasbir fa-inna Allahala yudeeAAu ajra almuhsineen","juz":13,"page":246},{"s":12,"a":91,"key":"12:91","ar":"قَالُوا۟ تَٱللَّهِ لَقَدْ ءَاثَرَكَ ٱللَّهُ عَلَيْنَا وَإِن كُنَّا لَخَـٰطِـِٔينَ","en":"They said, \"By Allāh, certainly has Allāh preferred you over us, and indeed, we have been sinners.\"","tr":"Qaloo tallahi laqad atharakaAllahu AAalayna wa-in kunna lakhati-een","juz":13,"page":246},{"s":12,"a":92,"key":"12:92","ar":"قَالَ لَا تَثْرِيبَ عَلَيْكُمُ ٱلْيَوْمَ ۖ يَغْفِرُ ٱللَّهُ لَكُمْ ۖ وَهُوَ أَرْحَمُ ٱلرَّٰحِمِينَ","en":"He said, \"No blame will there be upon you today. May Allāh forgive you; and He is the most merciful of the merciful.","tr":"Qala la tathreeba AAalaykumualyawma yaghfiru Allahu lakum wahuwa arhamu arrahimeen","juz":13,"page":246},{"s":12,"a":93,"key":"12:93","ar":"ٱذْهَبُوا۟ بِقَمِيصِى هَـٰذَا فَأَلْقُوهُ عَلَىٰ وَجْهِ أَبِى يَأْتِ بَصِيرًا وَأْتُونِى بِأَهْلِكُمْ أَجْمَعِينَ","en":"Take this, my shirt, and cast it over the face of my father; he will become seeing. And bring me your family, all together.\"","tr":"Ithhaboo biqameesee hathafaalqoohu AAala wajhi abee ya/ti baseeran wa/tooneebi-ahlikum ajmaAAeen","juz":13,"page":246},{"s":12,"a":94,"key":"12:94","ar":"وَلَمَّا فَصَلَتِ ٱلْعِيرُ قَالَ أَبُوهُمْ إِنِّى لَأَجِدُ رِيحَ يُوسُفَ ۖ لَوْلَآ أَن تُفَنِّدُونِ","en":"And when the caravan departed [from Egypt], their father said,1 \"Indeed, I find the smell of Joseph [and would say that he was alive] if you did not think me weakened in mind.\"","tr":"Walamma fasalati alAAeeru qalaaboohum innee laajidu reeha yoosufa lawla antufannidoon","juz":13,"page":246},{"s":12,"a":95,"key":"12:95","ar":"قَالُوا۟ تَٱللَّهِ إِنَّكَ لَفِى ضَلَـٰلِكَ ٱلْقَدِيمِ","en":"They said, \"By Allāh, indeed you are in your [same] old error.\"","tr":"Qaloo tallahi innakalafee dalalika alqadeem","juz":13,"page":246},{"s":12,"a":96,"key":"12:96","ar":"فَلَمَّآ أَن جَآءَ ٱلْبَشِيرُ أَلْقَىٰهُ عَلَىٰ وَجْهِهِۦ فَٱرْتَدَّ بَصِيرًا ۖ قَالَ أَلَمْ أَقُل لَّكُمْ إِنِّىٓ أَعْلَمُ مِنَ ٱللَّهِ مَا لَا تَعْلَمُونَ","en":"And when the bearer of good tidings1 arrived, he cast it over his face, and he returned [once again] seeing. He said, \"Did I not tell you that I know from Allāh that which you do not know?\"","tr":"Falamma an jaa albasheeru alqahuAAala wajhihi fartadda baseeran qalaalam aqul lakum innee aAAlamu mina Allahi ma lataAAlamoon","juz":13,"page":247},{"s":12,"a":97,"key":"12:97","ar":"قَالُوا۟ يَـٰٓأَبَانَا ٱسْتَغْفِرْ لَنَا ذُنُوبَنَآ إِنَّا كُنَّا خَـٰطِـِٔينَ","en":"They said, \"O our father, ask for us forgiveness of our sins; indeed, we have been sinners.\"","tr":"Qaloo ya abanaistaghfir lana thunoobana inna kunnakhati-een","juz":13,"page":247},{"s":12,"a":98,"key":"12:98","ar":"قَالَ سَوْفَ أَسْتَغْفِرُ لَكُمْ رَبِّىٓ ۖ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ","en":"He said, \"I will ask forgiveness for you from my Lord. Indeed, it is He who is the Forgiving, the Merciful.\"","tr":"Qala sawfa astaghfiru lakum rabbeeinnahu huwa alghafooru arraheem","juz":13,"page":247},{"s":12,"a":99,"key":"12:99","ar":"فَلَمَّا دَخَلُوا۟ عَلَىٰ يُوسُفَ ءَاوَىٰٓ إِلَيْهِ أَبَوَيْهِ وَقَالَ ٱدْخُلُوا۟ مِصْرَ إِن شَآءَ ٱللَّهُ ءَامِنِينَ","en":"And when they entered upon Joseph, he took his parents to himself [i.e., embraced them] and said, \"Enter Egypt, Allāh willing, safe [and secure].\"","tr":"Falamma dakhaloo AAala yoosufaawa ilayhi abawayhi waqala odkhuloo misrain shaa Allahu amineen","juz":13,"page":247},{"s":12,"a":100,"key":"12:100","ar":"وَرَفَعَ أَبَوَيْهِ عَلَى ٱلْعَرْشِ وَخَرُّوا۟ لَهُۥ سُجَّدًا ۖ وَقَالَ يَـٰٓأَبَتِ هَـٰذَا تَأْوِيلُ رُءْيَـٰىَ مِن قَبْلُ قَدْ جَعَلَهَا رَبِّى حَقًّا ۖ وَقَدْ أَحْسَنَ بِىٓ إِذْ أَخْرَجَنِى مِنَ ٱلسِّجْنِ وَجَآءَ بِكُم مِّنَ ٱلْبَدْوِ مِنۢ بَعْدِ أَن نَّزَغَ ٱلشَّيْطَـٰنُ بَيْنِى وَبَيْنَ إِخْوَتِىٓ ۚ إِنَّ رَبِّى لَطِيفٌ لِّمَا يَشَآءُ ۚ إِنَّهُۥ هُوَ ٱلْعَلِيمُ ٱلْحَكِيمُ","en":"And he raised his parents upon the throne, and they bowed to him in prostration.1 And he said, \"O my father, this is the explanation of my vision of before. My Lord has made it reality. And He was certainly good to me when He took me out of prison and brought you [here] from bedouin life after Satan had induced [estrangement] between me and my brothers. Indeed, my Lord is Subtle2 in what He wills. Indeed, it is He who is the Knowing, the Wise.","tr":"WarafaAAa abawayhi AAala alAAarshiwakharroo lahu sujjadan waqala ya abati hathata/weelu ru/yaya min qablu qad jaAAalaha rabbee haqqanwaqad ahsana bee ith akhrajanee mina assijniwajaa bikum mina albadwi min baAAdi an nazagha ashshaytanubaynee wabayna ikhwatee inna rabbee lateefun limayashao innahu huwa alAAaleemu alhakeem","juz":13,"page":247},{"s":12,"a":101,"key":"12:101","ar":"۞ رَبِّ قَدْ ءَاتَيْتَنِى مِنَ ٱلْمُلْكِ وَعَلَّمْتَنِى مِن تَأْوِيلِ ٱلْأَحَادِيثِ ۚ فَاطِرَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ أَنتَ وَلِىِّۦ فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ ۖ تَوَفَّنِى مُسْلِمًا وَأَلْحِقْنِى بِٱلصَّـٰلِحِينَ","en":"My Lord, You have given me [something] of sovereignty and taught me of the interpretation of dreams. Creator of the heavens and earth, You are my protector in this world and the Hereafter. Cause me to die a Muslim and join me with the righteous.\"","tr":"Rabbi qad ataytanee mina almulkiwaAAallamtanee min ta/weeli al-ahadeethi fatira assamawatiwal-ardi anta waliyyee fee addunyawal-akhirati tawaffanee musliman waalhiqneebissaliheen","juz":13,"page":247},{"s":12,"a":102,"key":"12:102","ar":"ذَٰلِكَ مِنْ أَنۢبَآءِ ٱلْغَيْبِ نُوحِيهِ إِلَيْكَ ۖ وَمَا كُنتَ لَدَيْهِمْ إِذْ أَجْمَعُوٓا۟ أَمْرَهُمْ وَهُمْ يَمْكُرُونَ","en":"That is from the news of the unseen which We reveal, [O Muḥammad], to you. And you were not with them when they put together their plan while they conspired.","tr":"Thalika min anba-i alghaybinooheehi ilayka wama kunta ladayhim ithajmaAAoo amrahum wahum yamkuroon","juz":13,"page":247},{"s":12,"a":103,"key":"12:103","ar":"وَمَآ أَكْثَرُ ٱلنَّاسِ وَلَوْ حَرَصْتَ بِمُؤْمِنِينَ","en":"And most of the people, although you strive [for it], are not believers.","tr":"Wama aktharu annasiwalaw harasta bimu/mineen","juz":13,"page":247},{"s":12,"a":104,"key":"12:104","ar":"وَمَا تَسْـَٔلُهُمْ عَلَيْهِ مِنْ أَجْرٍ ۚ إِنْ هُوَ إِلَّا ذِكْرٌ لِّلْعَـٰلَمِينَ","en":"And you do not ask of them for it any payment. It is not except a reminder to the worlds.","tr":"Wama tas-aluhum AAalayhi min ajrinin huwa illa thikrun lilAAalameen","juz":13,"page":248},{"s":12,"a":105,"key":"12:105","ar":"وَكَأَيِّن مِّنْ ءَايَةٍ فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ يَمُرُّونَ عَلَيْهَا وَهُمْ عَنْهَا مُعْرِضُونَ","en":"And how many a sign within the heavens and earth do they pass over while they, therefrom, are turning away.","tr":"Wakaayyin min ayatin fee assamawatiwal-ardi yamurroona AAalayha wahum AAanhamuAAridoon","juz":13,"page":248},{"s":12,"a":106,"key":"12:106","ar":"وَمَا يُؤْمِنُ أَكْثَرُهُم بِٱللَّهِ إِلَّا وَهُم مُّشْرِكُونَ","en":"And most of them believe not in Allāh except while they associate others with Him.","tr":"Wama yu/minu aktharuhum billahiilla wahum mushrikoon","juz":13,"page":248},{"s":12,"a":107,"key":"12:107","ar":"أَفَأَمِنُوٓا۟ أَن تَأْتِيَهُمْ غَـٰشِيَةٌ مِّنْ عَذَابِ ٱللَّهِ أَوْ تَأْتِيَهُمُ ٱلسَّاعَةُ بَغْتَةً وَهُمْ لَا يَشْعُرُونَ","en":"Then do they feel secure that there will not come to them an overwhelming [aspect] of the punishment of Allāh or that the Hour will not come upon them suddenly while they do not perceive?","tr":"Afaaminoo an ta/tiyahum ghashiyatunmin AAathabi Allahi aw ta/tiyahumu assaAAatubaghtatan wahum la yashAAuroon","juz":13,"page":248},{"s":12,"a":108,"key":"12:108","ar":"قُلْ هَـٰذِهِۦ سَبِيلِىٓ أَدْعُوٓا۟ إِلَى ٱللَّهِ ۚ عَلَىٰ بَصِيرَةٍ أَنَا۠ وَمَنِ ٱتَّبَعَنِى ۖ وَسُبْحَـٰنَ ٱللَّهِ وَمَآ أَنَا۠ مِنَ ٱلْمُشْرِكِينَ","en":"Say, \"This is my way; I invite to Allāh with insight, I and those who follow me. And exalted is Allāh; and I am not of those who associate others with Him.\"","tr":"Qul hathihi sabeelee adAAoo ilaAllahi AAala baseeratin ana wamaniittabaAAanee wasubhana Allahi wama anamina almushrikeen","juz":13,"page":248},{"s":12,"a":109,"key":"12:109","ar":"وَمَآ أَرْسَلْنَا مِن قَبْلِكَ إِلَّا رِجَالًا نُّوحِىٓ إِلَيْهِم مِّنْ أَهْلِ ٱلْقُرَىٰٓ ۗ أَفَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ ۗ وَلَدَارُ ٱلْـَٔاخِرَةِ خَيْرٌ لِّلَّذِينَ ٱتَّقَوْا۟ ۗ أَفَلَا تَعْقِلُونَ","en":"And We sent not before you [as messengers] except men to whom We revealed from among the people of cities. So have they1 not traveled through the earth and observed how was the end of those before them? And the home of the Hereafter is best for those who fear Allāh; then will you not reason?","tr":"Wama arsalna min qablika illarijalan noohee ilayhim min ahli alquraafalam yaseeroo fee al-ardi fayanthurookayfa kana AAaqibatu allatheena min qablihimwaladaru al-akhirati khayrun lillatheenaittaqaw afala taAAqiloon","juz":13,"page":248},{"s":12,"a":110,"key":"12:110","ar":"حَتَّىٰٓ إِذَا ٱسْتَيْـَٔسَ ٱلرُّسُلُ وَظَنُّوٓا۟ أَنَّهُمْ قَدْ كُذِبُوا۟ جَآءَهُمْ نَصْرُنَا فَنُجِّىَ مَن نَّشَآءُ ۖ وَلَا يُرَدُّ بَأْسُنَا عَنِ ٱلْقَوْمِ ٱلْمُجْرِمِينَ","en":"[They continued] until, when the messengers despaired and were certain that they had been denied, there came to them Our victory, and whoever We willed was saved. And Our punishment cannot be repelled from the people who are criminals.","tr":"Hatta itha istay-asa arrusuluwathannoo annahum qad kuthiboo jaahumnasruna fanujjiya man nashao walayuraddu ba/suna AAani alqawmi almujrimeen","juz":13,"page":248},{"s":12,"a":111,"key":"12:111","ar":"لَقَدْ كَانَ فِى قَصَصِهِمْ عِبْرَةٌ لِّأُو۟لِى ٱلْأَلْبَـٰبِ ۗ مَا كَانَ حَدِيثًا يُفْتَرَىٰ وَلَـٰكِن تَصْدِيقَ ٱلَّذِى بَيْنَ يَدَيْهِ وَتَفْصِيلَ كُلِّ شَىْءٍ وَهُدًى وَرَحْمَةً لِّقَوْمٍ يُؤْمِنُونَ","en":"There was certainly in their stories a lesson for those of understanding. Never was it [i.e., the Qur’ān] a narration invented, but a confirmation of what was before it and a detailed explanation of all things and guidance and mercy for a people who believe.","tr":"Laqad kana fee qasasihimAAibratun li-olee al-albabi ma kana hadeethanyuftara walakin tasdeeqa allatheebayna yadayhi watafseela kulli shay-in wahudan warahmatanliqawmin yu/minoon","juz":13,"page":248},{"s":13,"a":1,"key":"13:1","ar":" الٓمٓر ۚ تِلْكَ ءَايَـٰتُ ٱلْكِتَـٰبِ ۗ وَٱلَّذِىٓ أُنزِلَ إِلَيْكَ مِن رَّبِّكَ ٱلْحَقُّ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يُؤْمِنُونَ","en":"Alif, Lām, Meem, Rā.1 These are the verses of the Book; and what has been revealed to you from your Lord is the truth, but most of the people do not believe.","tr":"Alif-lam-meem-ra tilka ayatualkitabi wallathee onzila ilayka minrabbika alhaqqu walakinna akthara annasila yu/minoon","juz":13,"page":249},{"s":13,"a":2,"key":"13:2","ar":"ٱللَّهُ ٱلَّذِى رَفَعَ ٱلسَّمَـٰوَٰتِ بِغَيْرِ عَمَدٍ تَرَوْنَهَا ۖ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۖ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ ۖ كُلٌّ يَجْرِى لِأَجَلٍ مُّسَمًّى ۚ يُدَبِّرُ ٱلْأَمْرَ يُفَصِّلُ ٱلْـَٔايَـٰتِ لَعَلَّكُم بِلِقَآءِ رَبِّكُمْ تُوقِنُونَ","en":"It is Allāh who erected the heavens without pillars that you [can] see; then He established Himself above the Throne1 and made subject2 the sun and the moon, each running [its course] for a specified term. He arranges [each] matter; He details the signs that you may, of the meeting with your Lord, be certain.","tr":"Allahu allathee rafaAAa assamawatibighayri AAamadin tarawnaha thumma istawa AAalaalAAarshi wasakhkhara ashshamsa walqamara kullunyajree li-ajalin musamman yudabbiru al-amra yufassilu al-ayatilaAAallakum biliqa-i rabbikum tooqinoon","juz":13,"page":249},{"s":13,"a":3,"key":"13:3","ar":"وَهُوَ ٱلَّذِى مَدَّ ٱلْأَرْضَ وَجَعَلَ فِيهَا رَوَٰسِىَ وَأَنْهَـٰرًا ۖ وَمِن كُلِّ ٱلثَّمَرَٰتِ جَعَلَ فِيهَا زَوْجَيْنِ ٱثْنَيْنِ ۖ يُغْشِى ٱلَّيْلَ ٱلنَّهَارَ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يَتَفَكَّرُونَ","en":"And it is He who spread the earth and placed therein firmly set mountains and rivers; and from all of the fruits He made therein two mates; He causes the night to cover the day. Indeed in that are signs for a people who give thought.","tr":"Wahuwa allathee madda al-ardawajaAAala feeha rawasiya waanharan waminkulli aththamarati jaAAala feeha zawjayniithnayni yughshee allayla annahara inna fee thalikalaayatin liqawmin yatafakkaroon","juz":13,"page":249},{"s":13,"a":4,"key":"13:4","ar":"وَفِى ٱلْأَرْضِ قِطَعٌ مُّتَجَـٰوِرَٰتٌ وَجَنَّـٰتٌ مِّنْ أَعْنَـٰبٍ وَزَرْعٌ وَنَخِيلٌ صِنْوَانٌ وَغَيْرُ صِنْوَانٍ يُسْقَىٰ بِمَآءٍ وَٰحِدٍ وَنُفَضِّلُ بَعْضَهَا عَلَىٰ بَعْضٍ فِى ٱلْأُكُلِ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يَعْقِلُونَ","en":"And within the land are neighboring plots and gardens of grapevines and crops and palm trees, [growing] several from a root or otherwise,1 watered with one water; but We make some of them exceed others in [quality of] fruit. Indeed in that are signs for a people who reason.","tr":"Wafee al-ardi qitaAAun mutajawiratunwajannatun min aAAnabin wazarAAun wanakheelun sinwanunwaghayru sinwanin yusqa bima-in wahidinwanufaddilu baAAdaha AAala baAAdinfee alokuli inna fee thalika laayatinliqawmin yaAAqiloon","juz":13,"page":249},{"s":13,"a":5,"key":"13:5","ar":"۞ وَإِن تَعْجَبْ فَعَجَبٌ قَوْلُهُمْ أَءِذَا كُنَّا تُرَٰبًا أَءِنَّا لَفِى خَلْقٍ جَدِيدٍ ۗ أُو۟لَـٰٓئِكَ ٱلَّذِينَ كَفَرُوا۟ بِرَبِّهِمْ ۖ وَأُو۟لَـٰٓئِكَ ٱلْأَغْلَـٰلُ فِىٓ أَعْنَاقِهِمْ ۖ وَأُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"And if you are astonished,1 [O Muḥammad] - then astonishing is their saying, \"When we are dust, will we indeed be [brought] into a new creation?\" Those are the ones who have disbelieved in their Lord, and those will have shackles2 upon their necks, and those are the companions of the Fire; they will abide therein eternally.","tr":"Wa-in taAAjab faAAajabun qawluhum a-ithakunna turaban a-inna lafee khalqin jadeedinola-ika allatheena kafaroo birabbihim waola-ikaal-aghlalu fee aAAnaqihim waola-ika as-habuannari hum feeha khalidoon","juz":13,"page":249},{"s":13,"a":6,"key":"13:6","ar":"وَيَسْتَعْجِلُونَكَ بِٱلسَّيِّئَةِ قَبْلَ ٱلْحَسَنَةِ وَقَدْ خَلَتْ مِن قَبْلِهِمُ ٱلْمَثُلَـٰتُ ۗ وَإِنَّ رَبَّكَ لَذُو مَغْفِرَةٍ لِّلنَّاسِ عَلَىٰ ظُلْمِهِمْ ۖ وَإِنَّ رَبَّكَ لَشَدِيدُ ٱلْعِقَابِ","en":"They impatiently urge you to bring about evil before good,1 while there has already occurred before them similar punishments [to what they demand]. And indeed, your Lord is the possessor of forgiveness for the people despite their wrongdoing, and indeed, your Lord is severe in penalty.","tr":"WayastaAAjiloonaka bissayyi-atiqabla alhasanati waqad khalat min qablihimu almathulatuwa-inna rabbaka lathoo maghfiratin linnasiAAala thulmihim wa-inna rabbaka lashadeedualAAiqab","juz":13,"page":250},{"s":13,"a":7,"key":"13:7","ar":"وَيَقُولُ ٱلَّذِينَ كَفَرُوا۟ لَوْلَآ أُنزِلَ عَلَيْهِ ءَايَةٌ مِّن رَّبِّهِۦٓ ۗ إِنَّمَآ أَنتَ مُنذِرٌ ۖ وَلِكُلِّ قَوْمٍ هَادٍ","en":"And those who disbelieved say, \"Why has a sign not been sent down to him from his Lord?\" You are only a warner, and for every people is a guide.","tr":"Wayaqoolu allatheena kafaroo lawlaonzila AAalayhi ayatun min rabbihi innama anta munthirunwalikulli qawmin had","juz":13,"page":250},{"s":13,"a":8,"key":"13:8","ar":"ٱللَّهُ يَعْلَمُ مَا تَحْمِلُ كُلُّ أُنثَىٰ وَمَا تَغِيضُ ٱلْأَرْحَامُ وَمَا تَزْدَادُ ۖ وَكُلُّ شَىْءٍ عِندَهُۥ بِمِقْدَارٍ","en":"Allāh knows what every female carries1 and what the wombs lose [prematurely] or exceed.2 And everything with Him is by due measure.","tr":"Allahu yaAAlamu ma tahmilukullu ontha wama tagheedu al-arhamuwama tazdadu wakullu shay-in AAindahu bimiqdar","juz":13,"page":250},{"s":13,"a":9,"key":"13:9","ar":"عَـٰلِمُ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ ٱلْكَبِيرُ ٱلْمُتَعَالِ","en":"[He is] Knower of the unseen and the witnessed, the Grand, the Exalted.","tr":"AAalimu alghaybi washshahadatialkabeeru almutaAAal","juz":13,"page":250},{"s":13,"a":10,"key":"13:10","ar":"سَوَآءٌ مِّنكُم مَّنْ أَسَرَّ ٱلْقَوْلَ وَمَن جَهَرَ بِهِۦ وَمَنْ هُوَ مُسْتَخْفٍۭ بِٱلَّيْلِ وَسَارِبٌۢ بِٱلنَّهَارِ","en":"It is the same [to Him] concerning you whether one conceals [his] speech or publicizes it and whether one is hidden by night or conspicuous [among others] by day.","tr":"Sawaon minkum man asarra alqawlawaman jahara bihi waman huwa mustakhfin billayli wasaribunbinnahar","juz":13,"page":250},{"s":13,"a":11,"key":"13:11","ar":"لَهُۥ مُعَقِّبَـٰتٌ مِّنۢ بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهِۦ يَحْفَظُونَهُۥ مِنْ أَمْرِ ٱللَّهِ ۗ إِنَّ ٱللَّهَ لَا يُغَيِّرُ مَا بِقَوْمٍ حَتَّىٰ يُغَيِّرُوا۟ مَا بِأَنفُسِهِمْ ۗ وَإِذَآ أَرَادَ ٱللَّهُ بِقَوْمٍ سُوٓءًا فَلَا مَرَدَّ لَهُۥ ۚ وَمَا لَهُم مِّن دُونِهِۦ مِن وَالٍ","en":"For him [i.e., each one] are successive [angels]1 before and behind him who protect him by the decree of Allāh.2 Indeed, Allāh will not change the condition of a people until they change what is in themselves. And when Allāh intends for a people ill,3 there is no repelling it. And there is not for them besides Him any patron.","tr":"Lahu muAAaqqibatun min bayni yadayhiwamin khalfihi yahfathoonahu min amri Allahiinna Allaha la yughayyiru ma biqawmin hattayughayyiroo ma bi-anfusihim wa-itha aradaAllahu biqawmin soo-an fala maradda lahu wamalahum min doonihi min wal","juz":13,"page":250},{"s":13,"a":12,"key":"13:12","ar":"هُوَ ٱلَّذِى يُرِيكُمُ ٱلْبَرْقَ خَوْفًا وَطَمَعًا وَيُنشِئُ ٱلسَّحَابَ ٱلثِّقَالَ","en":"It is He who shows you lightning, [causing] fear and aspiration, and generates the heavy clouds.","tr":"Huwa allathee yureekumu albarqakhawfan watamaAAan wayunshi-o assahaba aththiqal","juz":13,"page":250},{"s":13,"a":13,"key":"13:13","ar":"وَيُسَبِّحُ ٱلرَّعْدُ بِحَمْدِهِۦ وَٱلْمَلَـٰٓئِكَةُ مِنْ خِيفَتِهِۦ وَيُرْسِلُ ٱلصَّوَٰعِقَ فَيُصِيبُ بِهَا مَن يَشَآءُ وَهُمْ يُجَـٰدِلُونَ فِى ٱللَّهِ وَهُوَ شَدِيدُ ٱلْمِحَالِ","en":"And the thunder exalts [Allāh] with praise of Him - and the angels [as well] from fear of Him - and He sends thunderbolts and strikes therewith whom He wills while they dispute about Allāh; and He is severe in assault.","tr":"Wayusabbihu arraAAdu bihamdihiwalmala-ikatu min kheefatihi wayursilu assawaAAiqafayuseebu biha man yashao wahum yujadiloonafee Allahi wahuwa shadeedu almihal","juz":13,"page":250},{"s":13,"a":14,"key":"13:14","ar":"لَهُۥ دَعْوَةُ ٱلْحَقِّ ۖ وَٱلَّذِينَ يَدْعُونَ مِن دُونِهِۦ لَا يَسْتَجِيبُونَ لَهُم بِشَىْءٍ إِلَّا كَبَـٰسِطِ كَفَّيْهِ إِلَى ٱلْمَآءِ لِيَبْلُغَ فَاهُ وَمَا هُوَ بِبَـٰلِغِهِۦ ۚ وَمَا دُعَآءُ ٱلْكَـٰفِرِينَ إِلَّا فِى ضَلَـٰلٍ","en":"To Him [alone] is the supplication of truth. And those they call upon besides Him do not respond to them with a thing, except as one who stretches his hands toward water [from afar, calling it] to reach his mouth, but it will not reach it [thus].1 And the supplication of the disbelievers is not but in error [i.e., futility].","tr":"Lahu daAAwatu alhaqqi wallatheenayadAAoona min doonihi la yastajeeboona lahum bishay-in illakabasiti kaffayhi ila alma-iliyablugha fahu wama huwa bibalighihi wamaduAAao alkafireena illa fee dalal","juz":13,"page":251},{"s":13,"a":15,"key":"13:15","ar":"وَلِلَّهِ يَسْجُدُ مَن فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ طَوْعًا وَكَرْهًا وَظِلَـٰلُهُم بِٱلْغُدُوِّ وَٱلْـَٔاصَالِ ۩","en":"And to Allāh prostrates whoever is within the heavens and the earth, willingly or by compulsion, and their shadows [as well] in the mornings and the afternoons.","tr":"Walillahi yasjudu man fee assamawatiwal-ardi tawAAan wakarhan wathilaluhumbilghuduwwi wal-asal","juz":13,"page":251},{"s":13,"a":16,"key":"13:16","ar":"قُلْ مَن رَّبُّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ قُلِ ٱللَّهُ ۚ قُلْ أَفَٱتَّخَذْتُم مِّن دُونِهِۦٓ أَوْلِيَآءَ لَا يَمْلِكُونَ لِأَنفُسِهِمْ نَفْعًا وَلَا ضَرًّا ۚ قُلْ هَلْ يَسْتَوِى ٱلْأَعْمَىٰ وَٱلْبَصِيرُ أَمْ هَلْ تَسْتَوِى ٱلظُّلُمَـٰتُ وَٱلنُّورُ ۗ أَمْ جَعَلُوا۟ لِلَّهِ شُرَكَآءَ خَلَقُوا۟ كَخَلْقِهِۦ فَتَشَـٰبَهَ ٱلْخَلْقُ عَلَيْهِمْ ۚ قُلِ ٱللَّهُ خَـٰلِقُ كُلِّ شَىْءٍ وَهُوَ ٱلْوَٰحِدُ ٱلْقَهَّـٰرُ","en":"Say, \"Who is Lord of the heavens and earth?\" Say, \"Allāh.\" Say, \"Have you then taken besides Him allies not possessing [even] for themselves any benefit or any harm?\" Say, \"Is the blind equivalent to the seeing? Or is darkness equivalent to light? Or have they attributed to Allāh partners who created like His creation so that the creation [of each] seemed similar to them?\"1 Say, \"Allāh is the Creator of all things, and He is the One, the Prevailing.\"2","tr":"Qul man rabbu assamawatiwal-ardi quli Allahu qul afattakhathtummin doonihi awliyaa la yamlikoona li-anfusihimnafAAan wala darran qul hal yastawee al-aAAmawalbaseeru am hal tastawee aththulumatuwannooru am jaAAaloo lillahi shurakaakhalaqoo kakhalqihi fatashabaha alkhalqu AAalayhim quliAllahu khaliqu kulli shay-in wahuwa alwahidualqahhar","juz":13,"page":251},{"s":13,"a":17,"key":"13:17","ar":"أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً فَسَالَتْ أَوْدِيَةٌۢ بِقَدَرِهَا فَٱحْتَمَلَ ٱلسَّيْلُ زَبَدًا رَّابِيًا ۚ وَمِمَّا يُوقِدُونَ عَلَيْهِ فِى ٱلنَّارِ ٱبْتِغَآءَ حِلْيَةٍ أَوْ مَتَـٰعٍ زَبَدٌ مِّثْلُهُۥ ۚ كَذَٰلِكَ يَضْرِبُ ٱللَّهُ ٱلْحَقَّ وَٱلْبَـٰطِلَ ۚ فَأَمَّا ٱلزَّبَدُ فَيَذْهَبُ جُفَآءً ۖ وَأَمَّا مَا يَنفَعُ ٱلنَّاسَ فَيَمْكُثُ فِى ٱلْأَرْضِ ۚ كَذَٰلِكَ يَضْرِبُ ٱللَّهُ ٱلْأَمْثَالَ","en":"He sends down from the sky, rain, and valleys flow according to their capacity, and the torrent carries a rising foam. And from that [ore] which they heat in the fire, desiring adornments and utensils, is a foam like it. Thus Allāh presents [the example of] truth and falsehood. As for the foam, it vanishes, [being] cast off; but as for that which benefits the people, it remains on the earth. Thus does Allāh present examples.","tr":"Anzala mina assama-i maanfasalat awdiyatun biqadariha fahtamalaassaylu zabadan rabiyan wamimma yooqidoonaAAalayhi fee annari ibtighaa hilyatinaw mataAAin zabadun mithluhu kathalika yadribuAllahu alhaqqa walbatila faammaazzabadu fayathhabu jufaan waamma mayanfaAAu annasa fayamkuthu fee al-ardi kathalikayadribu Allahu al-amthal","juz":13,"page":251},{"s":13,"a":18,"key":"13:18","ar":"لِلَّذِينَ ٱسْتَجَابُوا۟ لِرَبِّهِمُ ٱلْحُسْنَىٰ ۚ وَٱلَّذِينَ لَمْ يَسْتَجِيبُوا۟ لَهُۥ لَوْ أَنَّ لَهُم مَّا فِى ٱلْأَرْضِ جَمِيعًا وَمِثْلَهُۥ مَعَهُۥ لَٱفْتَدَوْا۟ بِهِۦٓ ۚ أُو۟لَـٰٓئِكَ لَهُمْ سُوٓءُ ٱلْحِسَابِ وَمَأْوَىٰهُمْ جَهَنَّمُ ۖ وَبِئْسَ ٱلْمِهَادُ","en":"For those who have responded to their Lord is the best [reward], but those who did not respond to Him - if they had all that is in the earth entirely and the like of it with it, they would [attempt to] ransom themselves thereby. Those will have the worst account, and their refuge is Hell, and wretched is the resting place.","tr":"Lillatheena istajaboolirabbihimu alhusna wallatheena lamyastajeeboo lahu law anna lahum ma fee al-ardijameeAAan wamithlahu maAAahu laftadaw bihi ola-ikalahum soo-o alhisabi wama/wahum jahannamuwabi/sa almihad","juz":13,"page":251},{"s":13,"a":19,"key":"13:19","ar":"۞ أَفَمَن يَعْلَمُ أَنَّمَآ أُنزِلَ إِلَيْكَ مِن رَّبِّكَ ٱلْحَقُّ كَمَنْ هُوَ أَعْمَىٰٓ ۚ إِنَّمَا يَتَذَكَّرُ أُو۟لُوا۟ ٱلْأَلْبَـٰبِ","en":"Then is he who knows that what has been revealed to you from your Lord is the truth like one who is blind? They will only be reminded who are people of understanding -","tr":"Afaman yaAAlamu annama onzila ilaykamin rabbika alhaqqu kaman huwa aAAma innamayatathakkaru oloo al-albab","juz":13,"page":252},{"s":13,"a":20,"key":"13:20","ar":"ٱلَّذِينَ يُوفُونَ بِعَهْدِ ٱللَّهِ وَلَا يَنقُضُونَ ٱلْمِيثَـٰقَ","en":"Those who fulfill the covenant of Allāh and do not break the contract,","tr":"Allatheena yoofoona biAAahdi Allahiwala yanqudoona almeethaq","juz":13,"page":252},{"s":13,"a":21,"key":"13:21","ar":"وَٱلَّذِينَ يَصِلُونَ مَآ أَمَرَ ٱللَّهُ بِهِۦٓ أَن يُوصَلَ وَيَخْشَوْنَ رَبَّهُمْ وَيَخَافُونَ سُوٓءَ ٱلْحِسَابِ","en":"And those who join that which Allāh has ordered to be joined1 and fear their Lord and are afraid of the evil of [their] account,","tr":"Wallatheena yasiloonama amara Allahu bihi an yoosala wayakhshawnarabbahum wayakhafoona soo-a alhisab","juz":13,"page":252},{"s":13,"a":22,"key":"13:22","ar":"وَٱلَّذِينَ صَبَرُوا۟ ٱبْتِغَآءَ وَجْهِ رَبِّهِمْ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَأَنفَقُوا۟ مِمَّا رَزَقْنَـٰهُمْ سِرًّا وَعَلَانِيَةً وَيَدْرَءُونَ بِٱلْحَسَنَةِ ٱلسَّيِّئَةَ أُو۟لَـٰٓئِكَ لَهُمْ عُقْبَى ٱلدَّارِ","en":"And those who are patient, seeking the face [i.e., acceptance] of their Lord, and establish prayer and spend from what We have provided for them secretly and publicly and prevent evil with good - those will have the good consequence of [this] home1 -","tr":"Wallatheena sabarooibtighaa wajhi rabbihim waaqamoo assalatawaanfaqoo mimma razaqnahum sirran waAAalaniyatanwayadraoona bilhasanati assayyi-ata ola-ikalahum AAuqba addar","juz":13,"page":252},{"s":13,"a":23,"key":"13:23","ar":"جَنَّـٰتُ عَدْنٍ يَدْخُلُونَهَا وَمَن صَلَحَ مِنْ ءَابَآئِهِمْ وَأَزْوَٰجِهِمْ وَذُرِّيَّـٰتِهِمْ ۖ وَٱلْمَلَـٰٓئِكَةُ يَدْخُلُونَ عَلَيْهِم مِّن كُلِّ بَابٍ","en":"Gardens of perpetual residence; they will enter them with whoever were righteous among their forefathers, their spouses and their descendants. And the angels will enter upon them from every gate, [saying],","tr":"Jannatu AAadnin yadkhuloonahawaman salaha min aba-ihim waazwajihimwathurriyyatihim walmala-ikatuyadkhuloona AAalayhim min kulli bab","juz":13,"page":252},{"s":13,"a":24,"key":"13:24","ar":"سَلَـٰمٌ عَلَيْكُم بِمَا صَبَرْتُمْ ۚ فَنِعْمَ عُقْبَى ٱلدَّارِ","en":"\"Peace [i.e., security] be upon you for what you patiently endured. And excellent is the final home.\"","tr":"Salamun AAalaykum bima sabartumfaniAAma AAuqba addar","juz":13,"page":252},{"s":13,"a":25,"key":"13:25","ar":"وَٱلَّذِينَ يَنقُضُونَ عَهْدَ ٱللَّهِ مِنۢ بَعْدِ مِيثَـٰقِهِۦ وَيَقْطَعُونَ مَآ أَمَرَ ٱللَّهُ بِهِۦٓ أَن يُوصَلَ وَيُفْسِدُونَ فِى ٱلْأَرْضِ ۙ أُو۟لَـٰٓئِكَ لَهُمُ ٱللَّعْنَةُ وَلَهُمْ سُوٓءُ ٱلدَّارِ","en":"But those who break the covenant of Allāh after contracting it and sever that which Allāh has ordered to be joined and spread corruption on earth - for them is the curse, and they will have the worst home.1","tr":"Wallatheena yanqudoonaAAahda Allahi min baAAdi meethaqihi wayaqtaAAoonama amara Allahu bihi an yoosala wayufsidoonafee al-ardi ola-ika lahumu allaAAnatu walahum soo-oaddar","juz":13,"page":252},{"s":13,"a":26,"key":"13:26","ar":"ٱللَّهُ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ وَفَرِحُوا۟ بِٱلْحَيَوٰةِ ٱلدُّنْيَا وَمَا ٱلْحَيَوٰةُ ٱلدُّنْيَا فِى ٱلْـَٔاخِرَةِ إِلَّا مَتَـٰعٌ","en":"Allāh extends provision for whom He wills and restricts [it]. And they rejoice in the worldly life, while the worldly life is not, compared to the Hereafter, except [brief] enjoyment.","tr":"Allahu yabsutu arrizqaliman yashao wayaqdiru wafarihoo bilhayatiaddunya wama alhayatu addunyafee al-akhirati illa mataAA","juz":13,"page":252},{"s":13,"a":27,"key":"13:27","ar":"وَيَقُولُ ٱلَّذِينَ كَفَرُوا۟ لَوْلَآ أُنزِلَ عَلَيْهِ ءَايَةٌ مِّن رَّبِّهِۦ ۗ قُلْ إِنَّ ٱللَّهَ يُضِلُّ مَن يَشَآءُ وَيَهْدِىٓ إِلَيْهِ مَنْ أَنَابَ","en":"And those who disbelieved say, \"Why has a sign not been sent down to him from his Lord?\" Say, [O Muḥammad], \"Indeed, Allāh leaves astray whom He wills and guides to Himself whoever turns back [to Him] -","tr":"Wayaqoolu allatheena kafaroo lawlaonzila AAalayhi ayatun min rabbihi qul inna Allahayudillu man yashao wayahdee ilayhi man anab","juz":13,"page":252},{"s":13,"a":28,"key":"13:28","ar":"ٱلَّذِينَ ءَامَنُوا۟ وَتَطْمَئِنُّ قُلُوبُهُم بِذِكْرِ ٱللَّهِ ۗ أَلَا بِذِكْرِ ٱللَّهِ تَطْمَئِنُّ ٱلْقُلُوبُ","en":"Those who have believed and whose hearts are assured by the remembrance of Allāh. Unquestionably, by the remembrance of Allāh hearts are assured.\"","tr":"Allatheena amanoo watatma-innuquloobuhum bithikri Allahi ala bithikriAllahi tatma-innu alquloob","juz":13,"page":252},{"s":13,"a":29,"key":"13:29","ar":"ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ طُوبَىٰ لَهُمْ وَحُسْنُ مَـَٔابٍ","en":"Those who have believed and done righteous deeds - a good state is theirs and a good return.","tr":"Allatheena amanoo waAAamiloo assalihatitooba lahum wahusnu maab","juz":13,"page":253},{"s":13,"a":30,"key":"13:30","ar":"كَذَٰلِكَ أَرْسَلْنَـٰكَ فِىٓ أُمَّةٍ قَدْ خَلَتْ مِن قَبْلِهَآ أُمَمٌ لِّتَتْلُوَا۟ عَلَيْهِمُ ٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ وَهُمْ يَكْفُرُونَ بِٱلرَّحْمَـٰنِ ۚ قُلْ هُوَ رَبِّى لَآ إِلَـٰهَ إِلَّا هُوَ عَلَيْهِ تَوَكَّلْتُ وَإِلَيْهِ مَتَابِ","en":"Thus have We sent you to a community before which [other] communities have passed on so you might recite to them that which We revealed to you, while they disbelieve in the Most Merciful. Say, \"He is my Lord; there is no deity except Him. Upon Him I rely, and to Him is my return.\"","tr":"Kathalika arsalnaka feeommatin qad khalat min qabliha omamun litatluwa AAalayhimuallathee awhayna ilayka wahum yakfuroona birrahmaniqul huwa rabbee la ilaha illa huwa AAalayhitawakkaltu wa-ilayhi matab","juz":13,"page":253},{"s":13,"a":31,"key":"13:31","ar":"وَلَوْ أَنَّ قُرْءَانًا سُيِّرَتْ بِهِ ٱلْجِبَالُ أَوْ قُطِّعَتْ بِهِ ٱلْأَرْضُ أَوْ كُلِّمَ بِهِ ٱلْمَوْتَىٰ ۗ بَل لِّلَّهِ ٱلْأَمْرُ جَمِيعًا ۗ أَفَلَمْ يَا۟يْـَٔسِ ٱلَّذِينَ ءَامَنُوٓا۟ أَن لَّوْ يَشَآءُ ٱللَّهُ لَهَدَى ٱلنَّاسَ جَمِيعًا ۗ وَلَا يَزَالُ ٱلَّذِينَ كَفَرُوا۟ تُصِيبُهُم بِمَا صَنَعُوا۟ قَارِعَةٌ أَوْ تَحُلُّ قَرِيبًا مِّن دَارِهِمْ حَتَّىٰ يَأْتِىَ وَعْدُ ٱللَّهِ ۚ إِنَّ ٱللَّهَ لَا يُخْلِفُ ٱلْمِيعَادَ","en":"And if there was any Qur’ān [i.e., recitation] by which the mountains would be removed or the earth would be broken apart or the dead would be made to speak,1 [it would be this Qur’ān], but to Allāh belongs the affair entirely. Then have those who believed not accepted that had Allāh willed, He would have guided the people, all of them? And those who disbelieve do not cease to be struck, for what they have done, by calamity - or it will descend near their home - until there comes the promise of Allāh. Indeed, Allāh does not fail in [His] promise.","tr":"Walaw anna qur-anan suyyirat bihialjibalu aw quttiAAat bihi al-ardu awkullima bihi almawta bal lillahi al-amru jameeAAanafalam yay-asi allatheena amanoo an law yashaoAllahu lahada annasa jameeAAan walayazalu allatheena kafaroo tuseebuhum bimasanaAAoo qariAAatun aw tahullu qareeban mindarihim hatta ya/tiya waAAdu Allahiinna Allaha la yukhlifu almeeAAad","juz":13,"page":253},{"s":13,"a":32,"key":"13:32","ar":"وَلَقَدِ ٱسْتُهْزِئَ بِرُسُلٍ مِّن قَبْلِكَ فَأَمْلَيْتُ لِلَّذِينَ كَفَرُوا۟ ثُمَّ أَخَذْتُهُمْ ۖ فَكَيْفَ كَانَ عِقَابِ","en":"And already were [other] messengers ridiculed before you, and I extended the time of those who disbelieved; then I seized them, and how [terrible] was My penalty.","tr":"Walaqadi istuhzi-a birusulin min qablikafaamlaytu lillatheena kafaroo thumma akhathtuhumfakayfa kana AAiqab","juz":13,"page":253},{"s":13,"a":33,"key":"13:33","ar":"أَفَمَنْ هُوَ قَآئِمٌ عَلَىٰ كُلِّ نَفْسٍۭ بِمَا كَسَبَتْ ۗ وَجَعَلُوا۟ لِلَّهِ شُرَكَآءَ قُلْ سَمُّوهُمْ ۚ أَمْ تُنَبِّـُٔونَهُۥ بِمَا لَا يَعْلَمُ فِى ٱلْأَرْضِ أَم بِظَـٰهِرٍ مِّنَ ٱلْقَوْلِ ۗ بَلْ زُيِّنَ لِلَّذِينَ كَفَرُوا۟ مَكْرُهُمْ وَصُدُّوا۟ عَنِ ٱلسَّبِيلِ ۗ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِنْ هَادٍ","en":"Then is He who is a maintainer of every soul, [knowing] what it has earned, [like any other]? But to Allāh they have attributed partners. Say, \"Name them. Or do you inform Him of that1 which He knows not upon the earth or of what is apparent [i.e., alleged] of speech?\"2 Rather, their [own] plan has been made attractive to those who disbelieve, and they have been averted from the way. And whomever Allāh sends astray - there will be for him no guide.","tr":"Afaman huwa qa-imun AAalakulli nafsin bima kasabat wajaAAaloo lillahi shurakaaqul sammoohum am tunabbi-oonahu bima la yaAAlamufee al-ardi am bithahirin minaalqawli bal zuyyina lillatheena kafaroo makruhum wasuddooAAani assabeeli waman yudlili Allahu famalahu min had","juz":13,"page":253},{"s":13,"a":34,"key":"13:34","ar":"لَّهُمْ عَذَابٌ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَلَعَذَابُ ٱلْـَٔاخِرَةِ أَشَقُّ ۖ وَمَا لَهُم مِّنَ ٱللَّهِ مِن وَاقٍ","en":"For them will be punishment in the life of [this] world, and the punishment of the Hereafter is more severe. And they will not have from Allāh any protector.","tr":"Lahum AAathabun fee alhayatiaddunya walaAAathabu al-akhiratiashaqqu wama lahum mina Allahi min waq","juz":13,"page":253},{"s":13,"a":35,"key":"13:35","ar":"۞ مَّثَلُ ٱلْجَنَّةِ ٱلَّتِى وُعِدَ ٱلْمُتَّقُونَ ۖ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ۖ أُكُلُهَا دَآئِمٌ وَظِلُّهَا ۚ تِلْكَ عُقْبَى ٱلَّذِينَ ٱتَّقَوا۟ ۖ وَّعُقْبَى ٱلْكَـٰفِرِينَ ٱلنَّارُ","en":"The example [i.e., description] of Paradise, which the righteous have been promised, is [that] beneath it rivers flow. Its fruit is lasting, and its shade. That is the consequence for the righteous, and the consequence for the disbelievers is the Fire.","tr":"Mathalu aljannati allatee wuAAidaalmuttaqoona tajree min tahtiha al-anharuokuluha da-imun wathilluhatilka AAuqba allatheena ittaqaw waAAuqba alkafireenaannar","juz":13,"page":254},{"s":13,"a":36,"key":"13:36","ar":"وَٱلَّذِينَ ءَاتَيْنَـٰهُمُ ٱلْكِتَـٰبَ يَفْرَحُونَ بِمَآ أُنزِلَ إِلَيْكَ ۖ وَمِنَ ٱلْأَحْزَابِ مَن يُنكِرُ بَعْضَهُۥ ۚ قُلْ إِنَّمَآ أُمِرْتُ أَنْ أَعْبُدَ ٱللَّهَ وَلَآ أُشْرِكَ بِهِۦٓ ۚ إِلَيْهِ أَدْعُوا۟ وَإِلَيْهِ مَـَٔابِ","en":"And [the believers among] those to whom We have given the [previous] Scripture rejoice at what has been revealed to you, [O Muḥammad], but among the [opposing] factions are those who deny part of it [i.e., the Qur’ān]. Say, \"I have only been commanded to worship Allāh and not associate [anything] with Him. To Him I invite, and to Him is my return.\"","tr":"Wallatheena ataynahumualkitaba yafrahoona bima onzila ilaykawamina al-ahzabi man yunkiru baAAdahu qulinnama omirtu an aAAbuda Allaha wala oshrikabihi ilayhi adAAoo wa-ilayhi maab","juz":13,"page":254},{"s":13,"a":37,"key":"13:37","ar":"وَكَذَٰلِكَ أَنزَلْنَـٰهُ حُكْمًا عَرَبِيًّا ۚ وَلَئِنِ ٱتَّبَعْتَ أَهْوَآءَهُم بَعْدَ مَا جَآءَكَ مِنَ ٱلْعِلْمِ مَا لَكَ مِنَ ٱللَّهِ مِن وَلِىٍّ وَلَا وَاقٍ","en":"And thus We have revealed it as an Arabic legislation.1 And if you should follow their inclinations after what has come to you of knowledge, you would not have against Allāh any ally or any protector.","tr":"Wakathalika anzalnahu hukmanAAarabiyyan wala-ini ittabaAAta ahwaahum baAAda majaaka mina alAAilmi ma laka mina Allahi minwaliyyin wala waq","juz":13,"page":254},{"s":13,"a":38,"key":"13:38","ar":"وَلَقَدْ أَرْسَلْنَا رُسُلًا مِّن قَبْلِكَ وَجَعَلْنَا لَهُمْ أَزْوَٰجًا وَذُرِّيَّةً ۚ وَمَا كَانَ لِرَسُولٍ أَن يَأْتِىَ بِـَٔايَةٍ إِلَّا بِإِذْنِ ٱللَّهِ ۗ لِكُلِّ أَجَلٍ كِتَابٌ","en":"And We have already sent messengers before you and assigned to them wives and descendants. And it was not for a messenger to come with a sign except by permission of Allāh. For every term is a decree.","tr":"Walaqad arsalna rusulan min qablikawajaAAalna lahum azwajan wathurriyyatan wamakana lirasoolin an ya/tiya bi-ayatin illabi-ithni Allahi likulli ajalin kitab","juz":13,"page":254},{"s":13,"a":39,"key":"13:39","ar":"يَمْحُوا۟ ٱللَّهُ مَا يَشَآءُ وَيُثْبِتُ ۖ وَعِندَهُۥٓ أُمُّ ٱلْكِتَـٰبِ","en":"Allāh eliminates what He wills or confirms, and with Him is the Mother of the Book.1","tr":"Yamhoo Allahu ma yashaowayuthbitu waAAindahu ommu alkitab","juz":13,"page":254},{"s":13,"a":40,"key":"13:40","ar":"وَإِن مَّا نُرِيَنَّكَ بَعْضَ ٱلَّذِى نَعِدُهُمْ أَوْ نَتَوَفَّيَنَّكَ فَإِنَّمَا عَلَيْكَ ٱلْبَلَـٰغُ وَعَلَيْنَا ٱلْحِسَابُ","en":"And whether We show you part of what We promise them or take you in death, upon you is only the [duty of] notification, and upon Us is the account.","tr":"Wa-in ma nuriyannaka baAAdaallathee naAAiduhum aw natawaffayannaka fa-innamaAAalayka albalaghu waAAalayna alhisab","juz":13,"page":254},{"s":13,"a":41,"key":"13:41","ar":"أَوَلَمْ يَرَوْا۟ أَنَّا نَأْتِى ٱلْأَرْضَ نَنقُصُهَا مِنْ أَطْرَافِهَا ۚ وَٱللَّهُ يَحْكُمُ لَا مُعَقِّبَ لِحُكْمِهِۦ ۚ وَهُوَ سَرِيعُ ٱلْحِسَابِ","en":"Have they not seen that We set upon the land, reducing it from its borders?1 And Allāh decides; there is no adjuster of His decision. And He is swift in account.","tr":"Awa lam yaraw anna na/tee al-ardananqusuha min atrafiha wallahuyahkumu la muAAaqqiba lihukmihi wahuwasareeAAu alhisab","juz":13,"page":254},{"s":13,"a":42,"key":"13:42","ar":"وَقَدْ مَكَرَ ٱلَّذِينَ مِن قَبْلِهِمْ فَلِلَّهِ ٱلْمَكْرُ جَمِيعًا ۖ يَعْلَمُ مَا تَكْسِبُ كُلُّ نَفْسٍ ۗ وَسَيَعْلَمُ ٱلْكُفَّـٰرُ لِمَنْ عُقْبَى ٱلدَّارِ","en":"And those before them had plotted, but to Allāh belongs the plan entirely. He knows what every soul earns, and the disbelievers will know for whom is the final home.","tr":"Waqad makara allatheena min qablihimfalillahi almakru jameeAAan yaAAlamu ma taksibukullu nafsin wasayaAAlamu alkuffaru liman AAuqba addar","juz":13,"page":254},{"s":13,"a":43,"key":"13:43","ar":"وَيَقُولُ ٱلَّذِينَ كَفَرُوا۟ لَسْتَ مُرْسَلًا ۚ قُلْ كَفَىٰ بِٱللَّهِ شَهِيدًۢا بَيْنِى وَبَيْنَكُمْ وَمَنْ عِندَهُۥ عِلْمُ ٱلْكِتَـٰبِ","en":"And those who have disbelieved say, \"You are not a messenger.\" Say, [O Muḥammad], \"Sufficient is Allāh as Witness between me and you, and [the witness of] whoever has knowledge of the Scripture.\"1","tr":"Wayaqoolu allatheena kafaroo lastamursalan qul kafa billahi shaheedan bayneewabaynakum waman AAindahu AAilmu alkitab","juz":13,"page":255},{"s":14,"a":1,"key":"14:1","ar":" الٓر ۚ كِتَـٰبٌ أَنزَلْنَـٰهُ إِلَيْكَ لِتُخْرِجَ ٱلنَّاسَ مِنَ ٱلظُّلُمَـٰتِ إِلَى ٱلنُّورِ بِإِذْنِ رَبِّهِمْ إِلَىٰ صِرَٰطِ ٱلْعَزِيزِ ٱلْحَمِيدِ","en":"Alif, Lām, Rā.1 [This is] a Book which We have revealed to you, [O Muḥammad], that you might bring mankind out of darknesses into the light by permission of their Lord - to the path of the Exalted in Might, the Praiseworthy -","tr":"Alif-lam-ra kitabunanzalnahu ilayka litukhrija annasa mina aththulumatiila annoori bi-ithni rabbihim ila siratialAAazeezi alhameed","juz":13,"page":255},{"s":14,"a":2,"key":"14:2","ar":"ٱللَّهِ ٱلَّذِى لَهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَوَيْلٌ لِّلْكَـٰفِرِينَ مِنْ عَذَابٍ شَدِيدٍ","en":"Allāh, to whom belongs whatever is in the heavens and whatever is on the earth. And woe [i.e., destruction] to the disbelievers from a severe punishment -","tr":"Allahi allathee lahu mafee assamawati wama fee al-ardiwawaylun lilkafireena min AAathabin shadeed","juz":13,"page":255},{"s":14,"a":3,"key":"14:3","ar":"ٱلَّذِينَ يَسْتَحِبُّونَ ٱلْحَيَوٰةَ ٱلدُّنْيَا عَلَى ٱلْـَٔاخِرَةِ وَيَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَيَبْغُونَهَا عِوَجًا ۚ أُو۟لَـٰٓئِكَ فِى ضَلَـٰلٍۭ بَعِيدٍ","en":"The ones who prefer the worldly life over the Hereafter and avert [people] from the way of Allāh, seeking to make it [seem] deviant. Those are in extreme error.","tr":"Allatheena yastahibboona alhayataaddunya AAala al-akhirati wayasuddoonaAAan sabeeli Allahi wayabghoonaha AAiwajan ola-ikafee dalalin baAAeed","juz":13,"page":255},{"s":14,"a":4,"key":"14:4","ar":"وَمَآ أَرْسَلْنَا مِن رَّسُولٍ إِلَّا بِلِسَانِ قَوْمِهِۦ لِيُبَيِّنَ لَهُمْ ۖ فَيُضِلُّ ٱللَّهُ مَن يَشَآءُ وَيَهْدِى مَن يَشَآءُ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"And We did not send any messenger except [speaking] in the language of his people to state clearly for them, and Allāh sends astray [thereby] whom He wills1 and guides whom He wills. And He is the Exalted in Might, the Wise.","tr":"Wama arsalna min rasoolin illabilisani qawmihi liyubayyina lahum fayudillu Allahuman yashao wayahdee man yashao wahuwa alAAazeezu alhakeem","juz":13,"page":255},{"s":14,"a":5,"key":"14:5","ar":"وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِـَٔايَـٰتِنَآ أَنْ أَخْرِجْ قَوْمَكَ مِنَ ٱلظُّلُمَـٰتِ إِلَى ٱلنُّورِ وَذَكِّرْهُم بِأَيَّىٰمِ ٱللَّهِ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّكُلِّ صَبَّارٍ شَكُورٍ","en":"And We certainly sent Moses with Our signs, [saying], \"Bring out your people from darknesses into the light and remind them of the days1 of Allāh.\" Indeed in that are signs for everyone patient and grateful.","tr":"Walaqad arsalna moosa bi-ayatinaan akhrij qawmaka mina aththulumatiila annoori wathakkirhum bi-ayyamiAllahi inna fee thalika laayatinlikulli sabbarin shakoor","juz":13,"page":255},{"s":14,"a":6,"key":"14:6","ar":"وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِ ٱذْكُرُوا۟ نِعْمَةَ ٱللَّهِ عَلَيْكُمْ إِذْ أَنجَىٰكُم مِّنْ ءَالِ فِرْعَوْنَ يَسُومُونَكُمْ سُوٓءَ ٱلْعَذَابِ وَيُذَبِّحُونَ أَبْنَآءَكُمْ وَيَسْتَحْيُونَ نِسَآءَكُمْ ۚ وَفِى ذَٰلِكُم بَلَآءٌ مِّن رَّبِّكُمْ عَظِيمٌ","en":"And [recall, O Children of Israel], when Moses said to his people, \"Remember the favor of Allāh upon you when He saved you from the people of Pharaoh, who were afflicting you with the worst torment and were slaughtering your [newborn] sons and keeping your females alive. And in that was a great trial from your Lord.","tr":"Wa-ith qala moosaliqawmihi othkuroo niAAmata Allahi AAalaykum ithanjakum min ali firAAawna yasoomoonakum soo-a alAAathabiwayuthabbihoona abnaakum wayastahyoonanisaakum wafee thalikum balaon min rabbikumAAatheem","juz":13,"page":256},{"s":14,"a":7,"key":"14:7","ar":"وَإِذْ تَأَذَّنَ رَبُّكُمْ لَئِن شَكَرْتُمْ لَأَزِيدَنَّكُمْ ۖ وَلَئِن كَفَرْتُمْ إِنَّ عَذَابِى لَشَدِيدٌ","en":"And [remember] when your Lord proclaimed, 'If you are grateful, I will surely increase you [in favor]; but if you deny, indeed, My punishment is severe.'\"","tr":"Wa-ith taaththana rabbukumla-in shakartum laazeedannakum wala-in kafartum inna AAathabeelashadeed","juz":13,"page":256},{"s":14,"a":8,"key":"14:8","ar":"وَقَالَ مُوسَىٰٓ إِن تَكْفُرُوٓا۟ أَنتُمْ وَمَن فِى ٱلْأَرْضِ جَمِيعًا فَإِنَّ ٱللَّهَ لَغَنِىٌّ حَمِيدٌ","en":"And Moses said, \"If you should disbelieve, you and whoever is on the earth entirely - indeed, Allāh is Free of need and Praiseworthy.\"","tr":"Waqala moosa in takfuroo antumwaman fee al-ardi jameeAAan fa-inna Allahalaghaniyyun hameed","juz":13,"page":256},{"s":14,"a":9,"key":"14:9","ar":"أَلَمْ يَأْتِكُمْ نَبَؤُا۟ ٱلَّذِينَ مِن قَبْلِكُمْ قَوْمِ نُوحٍ وَعَادٍ وَثَمُودَ ۛ وَٱلَّذِينَ مِنۢ بَعْدِهِمْ ۛ لَا يَعْلَمُهُمْ إِلَّا ٱللَّهُ ۚ جَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَـٰتِ فَرَدُّوٓا۟ أَيْدِيَهُمْ فِىٓ أَفْوَٰهِهِمْ وَقَالُوٓا۟ إِنَّا كَفَرْنَا بِمَآ أُرْسِلْتُم بِهِۦ وَإِنَّا لَفِى شَكٍّ مِّمَّا تَدْعُونَنَآ إِلَيْهِ مُرِيبٍ","en":"Has there not reached you the news of those before you - the people of Noah and ʿAad and Thamūd and those after them? No one knows them [i.e., their number] but Allāh. Their messengers brought them clear proofs, but they returned their hands to their mouths1 and said, \"Indeed, we disbelieve in that with which you have been sent, and indeed we are, about that to which you invite us, in disquieting doubt.\"","tr":"Alam ya/tikum nabao allatheena minqablikum qawmi noohin waAAadin wathamooda wallatheenamin baAAdihim la yaAAlamuhum illa Allahu jaat-humrusuluhum bilbayyinati faraddoo aydiyahum fee afwahihimwaqaloo inna kafarna bima orsiltumbihi wa-inna lafee shakkin mimma tadAAoonanailayhi mureeb","juz":13,"page":256},{"s":14,"a":10,"key":"14:10","ar":"۞ قَالَتْ رُسُلُهُمْ أَفِى ٱللَّهِ شَكٌّ فَاطِرِ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ يَدْعُوكُمْ لِيَغْفِرَ لَكُم مِّن ذُنُوبِكُمْ وَيُؤَخِّرَكُمْ إِلَىٰٓ أَجَلٍ مُّسَمًّى ۚ قَالُوٓا۟ إِنْ أَنتُمْ إِلَّا بَشَرٌ مِّثْلُنَا تُرِيدُونَ أَن تَصُدُّونَا عَمَّا كَانَ يَعْبُدُ ءَابَآؤُنَا فَأْتُونَا بِسُلْطَـٰنٍ مُّبِينٍ","en":"Their messengers said, \"Can there be doubt about Allāh, Creator of the heavens and earth? He invites you that He may forgive you of your sins, and He delays you [i.e., your death] for a specified term.\" They said, \"You are not but men like us who wish to avert us from what our fathers were worshipping. So bring us a clear authority [i.e., evidence].\"","tr":"Qalat rusuluhum afee Allahishakkun fatiri assamawati wal-ardiyadAAookum liyaghfira lakum min thunoobikumwayu-akhkhirakum ila ajalin musamman qaloo in antumilla basharun mithluna tureedoona an tasuddoonaAAamma kana yaAAbudu abaonafa/toona bisultanin mubeen","juz":13,"page":256},{"s":14,"a":11,"key":"14:11","ar":"قَالَتْ لَهُمْ رُسُلُهُمْ إِن نَّحْنُ إِلَّا بَشَرٌ مِّثْلُكُمْ وَلَـٰكِنَّ ٱللَّهَ يَمُنُّ عَلَىٰ مَن يَشَآءُ مِنْ عِبَادِهِۦ ۖ وَمَا كَانَ لَنَآ أَن نَّأْتِيَكُم بِسُلْطَـٰنٍ إِلَّا بِإِذْنِ ٱللَّهِ ۚ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ","en":"Their messengers said to them, \"We are only men like you, but Allāh confers favor upon whom He wills of His servants. It has never been for us to bring you evidence except by permission of Allāh. And upon Allāh let the believers rely.","tr":"Qalat lahum rusuluhum in nahnuilla basharun mithlukum walakinna Allahayamunnu AAala man yashao min AAibadihi wamakana lana an na/tiyakum bisultanin illabi-ithni Allahi waAAala Allahifalyatawakkali almu/minoon","juz":13,"page":257},{"s":14,"a":12,"key":"14:12","ar":"وَمَا لَنَآ أَلَّا نَتَوَكَّلَ عَلَى ٱللَّهِ وَقَدْ هَدَىٰنَا سُبُلَنَا ۚ وَلَنَصْبِرَنَّ عَلَىٰ مَآ ءَاذَيْتُمُونَا ۚ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُتَوَكِّلُونَ","en":"And why should we not rely upon Allāh while He has guided us to our [good] ways. And we will surely be patient against whatever harm you should cause us. And upon Allāh let those who would rely [indeed] rely.\"","tr":"Wama lana allanatawakkala AAala Allahi waqad hadanasubulana walanasbiranna AAala ma athaytumoonawaAAala Allahi falyatawakkali almutawakkiloon","juz":13,"page":257},{"s":14,"a":13,"key":"14:13","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِرُسُلِهِمْ لَنُخْرِجَنَّكُم مِّنْ أَرْضِنَآ أَوْ لَتَعُودُنَّ فِى مِلَّتِنَا ۖ فَأَوْحَىٰٓ إِلَيْهِمْ رَبُّهُمْ لَنُهْلِكَنَّ ٱلظَّـٰلِمِينَ","en":"And those who disbelieved said to their messengers, \"We will surely drive you out of our land, or you must return to our religion.\" So their Lord inspired to them, \"We will surely destroy the wrongdoers.","tr":"Waqala allatheena kafaroolirusulihim lanukhrijannakum min ardina awlataAAoodunna fee millatina faawha ilayhim rabbuhumlanuhlikanna aththalimeen","juz":13,"page":257},{"s":14,"a":14,"key":"14:14","ar":"وَلَنُسْكِنَنَّكُمُ ٱلْأَرْضَ مِنۢ بَعْدِهِمْ ۚ ذَٰلِكَ لِمَنْ خَافَ مَقَامِى وَخَافَ وَعِيدِ","en":"And We will surely cause you to dwell in the land after them. That is for he who fears My position1 and fears My threat.\"","tr":"Walanuskinannakumu al-arda minbaAAdihim thalika liman khafa maqamee wakhafawaAAeed","juz":13,"page":257},{"s":14,"a":15,"key":"14:15","ar":"وَٱسْتَفْتَحُوا۟ وَخَابَ كُلُّ جَبَّارٍ عَنِيدٍ","en":"And they requested decision [i.e., victory from Allāh], and disappointed, [therefore], was every obstinate tyrant.","tr":"Wastaftahoo wakhabakullu jabbarin AAaneed","juz":13,"page":257},{"s":14,"a":16,"key":"14:16","ar":"مِّن وَرَآئِهِۦ جَهَنَّمُ وَيُسْقَىٰ مِن مَّآءٍ صَدِيدٍ","en":"Before him1 is Hell, and he will be given a drink of purulent water.2","tr":"Min wara-ihi jahannamu wayusqamin ma-in sadeed","juz":13,"page":257},{"s":14,"a":17,"key":"14:17","ar":"يَتَجَرَّعُهُۥ وَلَا يَكَادُ يُسِيغُهُۥ وَيَأْتِيهِ ٱلْمَوْتُ مِن كُلِّ مَكَانٍ وَمَا هُوَ بِمَيِّتٍ ۖ وَمِن وَرَآئِهِۦ عَذَابٌ غَلِيظٌ","en":"He will gulp it but will hardly [be able to] swallow it. And death will come to him from everywhere, but he is not to die. And before him is a massive punishment.","tr":"YatajarraAAuhu wala yakaduyuseeghuhu waya/teehi almawtu min kulli makanin wamahuwa bimayyitin wamin wara-ihi AAathabun ghaleeth","juz":13,"page":257},{"s":14,"a":18,"key":"14:18","ar":"مَّثَلُ ٱلَّذِينَ كَفَرُوا۟ بِرَبِّهِمْ ۖ أَعْمَـٰلُهُمْ كَرَمَادٍ ٱشْتَدَّتْ بِهِ ٱلرِّيحُ فِى يَوْمٍ عَاصِفٍ ۖ لَّا يَقْدِرُونَ مِمَّا كَسَبُوا۟ عَلَىٰ شَىْءٍ ۚ ذَٰلِكَ هُوَ ٱلضَّلَـٰلُ ٱلْبَعِيدُ","en":"The example of those who disbelieve in their Lord is [that] their deeds are like ashes which the wind blows forcefully on a stormy day; they are unable [to keep] from what they earned a [single] thing. That is what is extreme error.","tr":"Mathalu allatheena kafaroo birabbihimaAAmaluhum karamadin ishtaddat bihi arreehufee yawmin AAasifin la yaqdiroona mimmakasaboo AAala shay-in thalika huwa addalalualbaAAeed","juz":13,"page":257},{"s":14,"a":19,"key":"14:19","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۚ إِن يَشَأْ يُذْهِبْكُمْ وَيَأْتِ بِخَلْقٍ جَدِيدٍ","en":"Have you not seen [i.e., considered] that Allāh created the heavens and the earth in truth? If He wills, He can do away with you and produce a new creation.","tr":"Alam tara anna Allaha khalaqa assamawatiwal-arda bilhaqqi in yasha/ yuthhibkumwaya/ti bikhalqin jadeed","juz":13,"page":258},{"s":14,"a":20,"key":"14:20","ar":"وَمَا ذَٰلِكَ عَلَى ٱللَّهِ بِعَزِيزٍ","en":"And that is not difficult for Allāh.","tr":"Wama thalika AAala AllahibiAAazeez","juz":13,"page":258},{"s":14,"a":21,"key":"14:21","ar":"وَبَرَزُوا۟ لِلَّهِ جَمِيعًا فَقَالَ ٱلضُّعَفَـٰٓؤُا۟ لِلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا كُنَّا لَكُمْ تَبَعًا فَهَلْ أَنتُم مُّغْنُونَ عَنَّا مِنْ عَذَابِ ٱللَّهِ مِن شَىْءٍ ۚ قَالُوا۟ لَوْ هَدَىٰنَا ٱللَّهُ لَهَدَيْنَـٰكُمْ ۖ سَوَآءٌ عَلَيْنَآ أَجَزِعْنَآ أَمْ صَبَرْنَا مَا لَنَا مِن مَّحِيصٍ","en":"And they will come out [for judgement] before Allāh all together, and the weak will say to those who were arrogant, \"Indeed, we were your followers, so can you avail us anything against the punishment of Allāh?\" They will say, \"If Allāh had guided us, we would have guided you. It is all the same for us whether we show intolerance or are patient: there is for us no place of escape.\"","tr":"Wabarazoo lillahi jameeAAan faqalaadduAAafao lillatheena istakbarooinna kunna lakum tabaAAan fahal antum mughnoonaAAanna min AAathabi Allahi min shay-in qaloolaw hadana Allahu lahadaynakum sawaonAAalayna ajaziAAna am sabarna malana min mahees","juz":13,"page":258},{"s":14,"a":22,"key":"14:22","ar":"وَقَالَ ٱلشَّيْطَـٰنُ لَمَّا قُضِىَ ٱلْأَمْرُ إِنَّ ٱللَّهَ وَعَدَكُمْ وَعْدَ ٱلْحَقِّ وَوَعَدتُّكُمْ فَأَخْلَفْتُكُمْ ۖ وَمَا كَانَ لِىَ عَلَيْكُم مِّن سُلْطَـٰنٍ إِلَّآ أَن دَعَوْتُكُمْ فَٱسْتَجَبْتُمْ لِى ۖ فَلَا تَلُومُونِى وَلُومُوٓا۟ أَنفُسَكُم ۖ مَّآ أَنَا۠ بِمُصْرِخِكُمْ وَمَآ أَنتُم بِمُصْرِخِىَّ ۖ إِنِّى كَفَرْتُ بِمَآ أَشْرَكْتُمُونِ مِن قَبْلُ ۗ إِنَّ ٱلظَّـٰلِمِينَ لَهُمْ عَذَابٌ أَلِيمٌ","en":"And Satan will say when the matter has been concluded, \"Indeed, Allāh had promised you the promise of truth. And I promised you, but I betrayed you. But I had no authority over you except that I invited you, and you responded to me. So do not blame me; but blame yourselves. I cannot be called to your aid, nor can you be called to my aid. Indeed, I deny your association of me [with Allāh] before.1 Indeed, for the wrongdoers is a painful punishment.\"","tr":"Waqala ashshaytanulamma qudiya al-amru inna Allaha waAAadakumwaAAda alhaqqi wawaAAadtukum faakhlaftukum wama kanaliya AAalaykum min sultanin illa an daAAawtukum fastajabtumlee fala taloomoonee waloomoo anfusakum ma anabimusrikhikum wama antum bimusrikhiyya inneekafartu bima ashraktumooni min qablu inna aththalimeenalahum AAathabun aleem","juz":13,"page":258},{"s":14,"a":23,"key":"14:23","ar":"وَأُدْخِلَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا بِإِذْنِ رَبِّهِمْ ۖ تَحِيَّتُهُمْ فِيهَا سَلَـٰمٌ","en":"And those who believed and did righteous deeds will be admitted to gardens beneath which rivers flow, abiding eternally therein by permission of their Lord; and their greeting therein will be, \"Peace!\"","tr":"Waodkhila allatheena amanoowaAAamiloo assalihati jannatintajree min tahtiha al-anharu khalideenafeeha bi-ithni rabbihim tahiyyatuhum feehasalam","juz":13,"page":258},{"s":14,"a":24,"key":"14:24","ar":"أَلَمْ تَرَ كَيْفَ ضَرَبَ ٱللَّهُ مَثَلًا كَلِمَةً طَيِّبَةً كَشَجَرَةٍ طَيِّبَةٍ أَصْلُهَا ثَابِتٌ وَفَرْعُهَا فِى ٱلسَّمَآءِ","en":"Have you not considered how Allāh presents an example, [making] a good word like a good tree, whose root is firmly fixed and its branches [high] in the sky?","tr":"Alam tara kayfa daraba Allahumathalan kalimatan tayyibatan kashajaratin tayyibatinasluha thabitun wafarAAuha fee assama/-","juz":13,"page":258},{"s":14,"a":25,"key":"14:25","ar":"تُؤْتِىٓ أُكُلَهَا كُلَّ حِينٍۭ بِإِذْنِ رَبِّهَا ۗ وَيَضْرِبُ ٱللَّهُ ٱلْأَمْثَالَ لِلنَّاسِ لَعَلَّهُمْ يَتَذَكَّرُونَ","en":"It produces its fruit all the time, by permission of its Lord. And Allāh presents examples for the people that perhaps they will be reminded.","tr":"Tu/tee okulaha kulla heeninbi-ithni rabbiha wayadribu Allahual-amthala linnasi laAAallahum yatathakkaroon","juz":13,"page":259},{"s":14,"a":26,"key":"14:26","ar":"وَمَثَلُ كَلِمَةٍ خَبِيثَةٍ كَشَجَرَةٍ خَبِيثَةٍ ٱجْتُثَّتْ مِن فَوْقِ ٱلْأَرْضِ مَا لَهَا مِن قَرَارٍ","en":"And the example of a bad word is like a bad tree, uprooted from the surface of the earth, not having any stability.","tr":"Wamathalu kalimatin khabeethatinkashajaratin khabeethatin ijtuththat min fawqi al-ardi malaha min qarar","juz":13,"page":259},{"s":14,"a":27,"key":"14:27","ar":"يُثَبِّتُ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ بِٱلْقَوْلِ ٱلثَّابِتِ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَفِى ٱلْـَٔاخِرَةِ ۖ وَيُضِلُّ ٱللَّهُ ٱلظَّـٰلِمِينَ ۚ وَيَفْعَلُ ٱللَّهُ مَا يَشَآءُ","en":"Allāh keeps firm those who believe, with the firm word,1 in worldly life and in the Hereafter.2 And Allāh sends astray the wrongdoers. And Allāh does what He wills.","tr":"Yuthabbitu Allahu allatheena amanoobilqawli aththabiti fee alhayatiaddunya wafee al-akhirati wayudilluAllahu aththalimeenawayafAAalu Allahu ma yasha/","juz":13,"page":259},{"s":14,"a":28,"key":"14:28","ar":"۞ أَلَمْ تَرَ إِلَى ٱلَّذِينَ بَدَّلُوا۟ نِعْمَتَ ٱللَّهِ كُفْرًا وَأَحَلُّوا۟ قَوْمَهُمْ دَارَ ٱلْبَوَارِ","en":"Have you not considered those who exchanged the favor of Allāh for disbelief1 and settled their people [in] the home of ruin?","tr":"Alam tara ila allatheenabaddaloo niAAmata Allahi kufran waahalloo qawmahumdara albawar","juz":13,"page":259},{"s":14,"a":29,"key":"14:29","ar":"جَهَنَّمَ يَصْلَوْنَهَا ۖ وَبِئْسَ ٱلْقَرَارُ","en":"[It is] Hell, which they will [enter to] burn, and wretched is the settlement.","tr":"Jahannama yaslawnaha wabi/saalqarar","juz":13,"page":259},{"s":14,"a":30,"key":"14:30","ar":"وَجَعَلُوا۟ لِلَّهِ أَندَادًا لِّيُضِلُّوا۟ عَن سَبِيلِهِۦ ۗ قُلْ تَمَتَّعُوا۟ فَإِنَّ مَصِيرَكُمْ إِلَى ٱلنَّارِ","en":"And they have attributed to Allāh equals to mislead [people] from His way. Say, \"Enjoy yourselves, for indeed, your destination is the Fire.\"","tr":"WajaAAaloo lillahi andadanliyudilloo AAan sabeelihi qul tamattaAAoo fa-inna maseerakumila annar","juz":13,"page":259},{"s":14,"a":31,"key":"14:31","ar":"قُل لِّعِبَادِىَ ٱلَّذِينَ ءَامَنُوا۟ يُقِيمُوا۟ ٱلصَّلَوٰةَ وَيُنفِقُوا۟ مِمَّا رَزَقْنَـٰهُمْ سِرًّا وَعَلَانِيَةً مِّن قَبْلِ أَن يَأْتِىَ يَوْمٌ لَّا بَيْعٌ فِيهِ وَلَا خِلَـٰلٌ","en":"[O Muḥammad], tell My servants who have believed to establish prayer and spend from what We have provided them, secretly and publicly, before a Day comes in which there will be no exchange [i.e., ransom], nor any friendships.","tr":"Qul liAAibadiya allatheena amanooyuqeemoo assalata wayunfiqoo mimmarazaqnahum sirran waAAalaniyatan min qabli anya/tiya yawmun la bayAAun feehi wala khilal","juz":13,"page":259},{"s":14,"a":32,"key":"14:32","ar":"ٱللَّهُ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَأَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً فَأَخْرَجَ بِهِۦ مِنَ ٱلثَّمَرَٰتِ رِزْقًا لَّكُمْ ۖ وَسَخَّرَ لَكُمُ ٱلْفُلْكَ لِتَجْرِىَ فِى ٱلْبَحْرِ بِأَمْرِهِۦ ۖ وَسَخَّرَ لَكُمُ ٱلْأَنْهَـٰرَ","en":"It is Allāh who created the heavens and the earth and sent down rain from the sky and produced thereby some fruits as provision for you and subjected for you1 the ships to sail through the sea by His command and subjected for you the rivers.","tr":"Allahu allathee khalaqa assamawatiwal-arda waanzala mina assama-i maanfaakhraja bihi mina aththamarati rizqan lakumwasakhkhara lakumu alfulka litajriya fee albahri bi-amrihiwasakhkhara lakumu al-anhar","juz":13,"page":259},{"s":14,"a":33,"key":"14:33","ar":"وَسَخَّرَ لَكُمُ ٱلشَّمْسَ وَٱلْقَمَرَ دَآئِبَيْنِ ۖ وَسَخَّرَ لَكُمُ ٱلَّيْلَ وَٱلنَّهَارَ","en":"And He subjected for you the sun and the moon, continuous [in orbit], and subjected for you the night and the day.","tr":"Wasakhkhara lakumu ashshamsa walqamarada-ibayni wasakhkhara lakumu allayla wannahar","juz":13,"page":259},{"s":14,"a":34,"key":"14:34","ar":"وَءَاتَىٰكُم مِّن كُلِّ مَا سَأَلْتُمُوهُ ۚ وَإِن تَعُدُّوا۟ نِعْمَتَ ٱللَّهِ لَا تُحْصُوهَآ ۗ إِنَّ ٱلْإِنسَـٰنَ لَظَلُومٌ كَفَّارٌ","en":"And He gave you from all you asked of Him.1 And if you should count the favor [i.e., blessings] of Allāh, you could not enumerate them. Indeed, mankind is [generally] most unjust and ungrateful.2","tr":"Waatakum min kulli masaaltumoohu wa-in taAAuddoo niAAmata Allahi la tuhsoohainna al-insana lathaloomun kaffar","juz":13,"page":260},{"s":14,"a":35,"key":"14:35","ar":"وَإِذْ قَالَ إِبْرَٰهِيمُ رَبِّ ٱجْعَلْ هَـٰذَا ٱلْبَلَدَ ءَامِنًا وَٱجْنُبْنِى وَبَنِىَّ أَن نَّعْبُدَ ٱلْأَصْنَامَ","en":"And [mention, O Muḥammad], when Abraham said, \"My Lord, make this city [i.e., Makkah] secure and keep me and my sons away from worshipping idols.","tr":"Wa-ith qala ibraheemurabbi ijAAal hatha albalada aminan wajnubneewabaniyya an naAAbuda al-asnam","juz":13,"page":260},{"s":14,"a":36,"key":"14:36","ar":"رَبِّ إِنَّهُنَّ أَضْلَلْنَ كَثِيرًا مِّنَ ٱلنَّاسِ ۖ فَمَن تَبِعَنِى فَإِنَّهُۥ مِنِّى ۖ وَمَنْ عَصَانِى فَإِنَّكَ غَفُورٌ رَّحِيمٌ","en":"My Lord, indeed they have led astray many among the people. So whoever follows me - then he is of me;1 and whoever disobeys me - indeed, You are [yet] Forgiving and Merciful.","tr":"Rabbi innahunna adlalna katheeranmina annasi faman tabiAAanee fa-innahu minneewaman AAasanee fa-innaka ghafoorun raheem","juz":13,"page":260},{"s":14,"a":37,"key":"14:37","ar":"رَّبَّنَآ إِنِّىٓ أَسْكَنتُ مِن ذُرِّيَّتِى بِوَادٍ غَيْرِ ذِى زَرْعٍ عِندَ بَيْتِكَ ٱلْمُحَرَّمِ رَبَّنَا لِيُقِيمُوا۟ ٱلصَّلَوٰةَ فَٱجْعَلْ أَفْـِٔدَةً مِّنَ ٱلنَّاسِ تَهْوِىٓ إِلَيْهِمْ وَٱرْزُقْهُم مِّنَ ٱلثَّمَرَٰتِ لَعَلَّهُمْ يَشْكُرُونَ","en":"Our Lord, I have settled some of my descendants in an uncultivated valley near Your sacred House, our Lord, that they may establish prayer. So make hearts among the people incline toward them and provide for them from the fruits that they might be grateful.","tr":"Rabbana innee askantu min thurriyyateebiwadin ghayri thee zarAAin AAinda baytika almuharramirabbana liyuqeemoo assalata fajAAalaf-idatan mina annasi tahwee ilayhim warzuqhummina aththamarati laAAallahum yashkuroon","juz":13,"page":260},{"s":14,"a":38,"key":"14:38","ar":"رَبَّنَآ إِنَّكَ تَعْلَمُ مَا نُخْفِى وَمَا نُعْلِنُ ۗ وَمَا يَخْفَىٰ عَلَى ٱللَّهِ مِن شَىْءٍ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ","en":"Our Lord, indeed You know what we conceal and what we declare, and nothing is hidden from Allāh on the earth or in the heaven.","tr":"Rabbana innaka taAAlamu manukhfee wama nuAAlinu wama yakhfa AAalaAllahi min shay-in fee al-ardi wala fee assama/-","juz":13,"page":260},{"s":14,"a":39,"key":"14:39","ar":"ٱلْحَمْدُ لِلَّهِ ٱلَّذِى وَهَبَ لِى عَلَى ٱلْكِبَرِ إِسْمَـٰعِيلَ وَإِسْحَـٰقَ ۚ إِنَّ رَبِّى لَسَمِيعُ ٱلدُّعَآءِ","en":"Praise to Allāh, who has granted to me in old age Ishmael and Isaac. Indeed, my Lord is the Hearer of supplication.","tr":"Alhamdu lillahi allatheewahaba lee AAala alkibari ismaAAeela wa-ishaqainna rabbee lasameeAAu adduAAa/-","juz":13,"page":260},{"s":14,"a":40,"key":"14:40","ar":"رَبِّ ٱجْعَلْنِى مُقِيمَ ٱلصَّلَوٰةِ وَمِن ذُرِّيَّتِى ۚ رَبَّنَا وَتَقَبَّلْ دُعَآءِ","en":"My Lord, make me an establisher of prayer, and [many] from my descendants. Our Lord, and accept my supplication.","tr":"Rabbi ijAAalnee muqeema assalatiwamin thurriyyatee rabbana wtaqabbal duAAa/-","juz":13,"page":260},{"s":14,"a":41,"key":"14:41","ar":"رَبَّنَا ٱغْفِرْ لِى وَلِوَٰلِدَىَّ وَلِلْمُؤْمِنِينَ يَوْمَ يَقُومُ ٱلْحِسَابُ","en":"Our Lord, forgive me and my parents and the believers the Day the account is established.\"","tr":"Rabbana ighfir lee waliwalidayyawalilmu/mineena yawma yaqoomu alhisab","juz":13,"page":260},{"s":14,"a":42,"key":"14:42","ar":"وَلَا تَحْسَبَنَّ ٱللَّهَ غَـٰفِلًا عَمَّا يَعْمَلُ ٱلظَّـٰلِمُونَ ۚ إِنَّمَا يُؤَخِّرُهُمْ لِيَوْمٍ تَشْخَصُ فِيهِ ٱلْأَبْصَـٰرُ","en":"And never think that Allāh is unaware of what the wrongdoers do. He only delays them [i.e., their account] for a Day when eyes will stare [in horror].","tr":"Wala tahsabanna Allahaghafilan AAamma yaAAmalu aththalimoonainnama yu-akhkhiruhum liyawmin tashkhasu feehial-absar","juz":13,"page":260},{"s":14,"a":43,"key":"14:43","ar":"مُهْطِعِينَ مُقْنِعِى رُءُوسِهِمْ لَا يَرْتَدُّ إِلَيْهِمْ طَرْفُهُمْ ۖ وَأَفْـِٔدَتُهُمْ هَوَآءٌ","en":"Racing ahead, their heads raised up, their glance does not come back to them,1 and their hearts are void.","tr":"MuhtiAAeena muqniAAee ruoosihim layartaddu ilayhim tarfuhum waaf-idatuhum hawa/","juz":13,"page":261},{"s":14,"a":44,"key":"14:44","ar":"وَأَنذِرِ ٱلنَّاسَ يَوْمَ يَأْتِيهِمُ ٱلْعَذَابُ فَيَقُولُ ٱلَّذِينَ ظَلَمُوا۟ رَبَّنَآ أَخِّرْنَآ إِلَىٰٓ أَجَلٍ قَرِيبٍ نُّجِبْ دَعْوَتَكَ وَنَتَّبِعِ ٱلرُّسُلَ ۗ أَوَلَمْ تَكُونُوٓا۟ أَقْسَمْتُم مِّن قَبْلُ مَا لَكُم مِّن زَوَالٍ","en":"And, [O Muḥammad], warn the people of a Day when the punishment will come to them and those who did wrong will say, \"Our Lord, delay us for a short term; we will answer Your call and follow the messengers.\" [But it will be said], \"Had you not sworn, before, that for you there would be no cessation?1","tr":"Waanthiri annasa yawmaya/teehimu alAAathabu fayaqoolu allatheena thalamoorabbana akhkhirna ila ajalin qareebin nujibdaAAwataka wanattabiAAi arrusula awa lam takoonooaqsamtum min qablu ma lakum min zawal","juz":13,"page":261},{"s":14,"a":45,"key":"14:45","ar":"وَسَكَنتُمْ فِى مَسَـٰكِنِ ٱلَّذِينَ ظَلَمُوٓا۟ أَنفُسَهُمْ وَتَبَيَّنَ لَكُمْ كَيْفَ فَعَلْنَا بِهِمْ وَضَرَبْنَا لَكُمُ ٱلْأَمْثَالَ","en":"And you lived among the dwellings of those who wronged themselves, and it had become clear to you how We dealt with them. And We presented for you [many] examples.\"","tr":"Wasakantum fee masakini allatheenathalamoo anfusahum watabayyana lakum kayfa faAAalnabihim wadarabna lakumu al-amthal","juz":13,"page":261},{"s":14,"a":46,"key":"14:46","ar":"وَقَدْ مَكَرُوا۟ مَكْرَهُمْ وَعِندَ ٱللَّهِ مَكْرُهُمْ وَإِن كَانَ مَكْرُهُمْ لِتَزُولَ مِنْهُ ٱلْجِبَالُ","en":"And they had planned their plan, but with Allāh is [recorded] their plan, even if their plan had been [sufficient] to do away with the mountains.1","tr":"Waqad makaroo makrahum waAAinda Allahimakruhum wa-in kana makruhum litazoola minhu aljibal","juz":13,"page":261},{"s":14,"a":47,"key":"14:47","ar":"فَلَا تَحْسَبَنَّ ٱللَّهَ مُخْلِفَ وَعْدِهِۦ رُسُلَهُۥٓ ۗ إِنَّ ٱللَّهَ عَزِيزٌ ذُو ٱنتِقَامٍ","en":"So never think that Allāh will fail in His promise to His messengers. Indeed, Allāh is Exalted in Might and Owner of Retribution.1","tr":"Fala tahsabanna Allahamukhlifa waAAdihi rusulahu inna Allaha AAazeezun thoointiqam","juz":13,"page":261},{"s":14,"a":48,"key":"14:48","ar":"يَوْمَ تُبَدَّلُ ٱلْأَرْضُ غَيْرَ ٱلْأَرْضِ وَٱلسَّمَـٰوَٰتُ ۖ وَبَرَزُوا۟ لِلَّهِ ٱلْوَٰحِدِ ٱلْقَهَّارِ","en":"[It will be] on the Day the earth will be replaced by another earth, and the heavens [as well], and they [i.e., all creatures] will come out before Allāh, the One, the Prevailing,","tr":"Yawma tubaddalu al-ardu ghayra al-ardiwassamawatu wabarazoo lillahi alwahidialqahhar","juz":13,"page":261},{"s":14,"a":49,"key":"14:49","ar":"وَتَرَى ٱلْمُجْرِمِينَ يَوْمَئِذٍ مُّقَرَّنِينَ فِى ٱلْأَصْفَادِ","en":"And you will see the criminals that Day bound together in irons,","tr":"Watara almujrimeena yawma-ithinmuqarraneena fee al-asfad","juz":13,"page":261},{"s":14,"a":50,"key":"14:50","ar":"سَرَابِيلُهُم مِّن قَطِرَانٍ وَتَغْشَىٰ وُجُوهَهُمُ ٱلنَّارُ","en":"Their garments of liquid pitch and their faces covered by the Fire","tr":"Sarabeeluhum min qatraninwataghsha wujoohahumu annar","juz":13,"page":261},{"s":14,"a":51,"key":"14:51","ar":"لِيَجْزِىَ ٱللَّهُ كُلَّ نَفْسٍ مَّا كَسَبَتْ ۚ إِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ","en":"So that Allāh will recompense every soul for what it earned. Indeed, Allāh is swift in account.","tr":"Liyajziya Allahu kulla nafsin makasabat inna Allaha sareeAAu alhisab","juz":13,"page":261},{"s":14,"a":52,"key":"14:52","ar":"هَـٰذَا بَلَـٰغٌ لِّلنَّاسِ وَلِيُنذَرُوا۟ بِهِۦ وَلِيَعْلَمُوٓا۟ أَنَّمَا هُوَ إِلَـٰهٌ وَٰحِدٌ وَلِيَذَّكَّرَ أُو۟لُوا۟ ٱلْأَلْبَـٰبِ","en":"This [Qur’ān] is notification for the people that they may be warned thereby and that they may know that He is but one God and that those of understanding will be reminded.","tr":"Hatha balaghun linnasiwaliyuntharoo bihi waliyaAAlamoo annama huwa ilahunwahidun waliyaththakkara oloo al-albab","juz":13,"page":261},{"s":15,"a":1,"key":"15:1","ar":" الٓر ۚ تِلْكَ ءَايَـٰتُ ٱلْكِتَـٰبِ وَقُرْءَانٍ مُّبِينٍ","en":"Alif, Lām, Rā.1 These are the verses of the Book and a clear Qur’ān [i.e., recitation].","tr":"Alif-lam-ra tilka ayatualkitabi waqur-anin mubeen","juz":14,"page":262},{"s":15,"a":2,"key":"15:2","ar":"رُّبَمَا يَوَدُّ ٱلَّذِينَ كَفَرُوا۟ لَوْ كَانُوا۟ مُسْلِمِينَ","en":"Perhaps those who disbelieve will wish1 that they had been Muslims.","tr":"Rubama yawaddu allatheenakafaroo law kanoo muslimeen","juz":14,"page":262},{"s":15,"a":3,"key":"15:3","ar":"ذَرْهُمْ يَأْكُلُوا۟ وَيَتَمَتَّعُوا۟ وَيُلْهِهِمُ ٱلْأَمَلُ ۖ فَسَوْفَ يَعْلَمُونَ","en":"Let them eat and enjoy themselves and be diverted by [false] hope, for they are going to know.","tr":"Tharhum ya/kuloo wayatamattaAAoowayulhihimu al-amalu fasawfa yaAAlamoon","juz":14,"page":262},{"s":15,"a":4,"key":"15:4","ar":"وَمَآ أَهْلَكْنَا مِن قَرْيَةٍ إِلَّا وَلَهَا كِتَابٌ مَّعْلُومٌ","en":"And We did not destroy any city but that for it was a known decree.","tr":"Wama ahlakna min qaryatin illawalaha kitabun maAAloom","juz":14,"page":262},{"s":15,"a":5,"key":"15:5","ar":"مَّا تَسْبِقُ مِنْ أُمَّةٍ أَجَلَهَا وَمَا يَسْتَـْٔخِرُونَ","en":"No nation will precede its term, nor will they remain thereafter.","tr":"Ma tasbiqu min ommatin ajalahawama yasta/khiroon","juz":14,"page":262},{"s":15,"a":6,"key":"15:6","ar":"وَقَالُوا۟ يَـٰٓأَيُّهَا ٱلَّذِى نُزِّلَ عَلَيْهِ ٱلذِّكْرُ إِنَّكَ لَمَجْنُونٌ","en":"And they say, \"O you upon whom the message has been sent down, indeed you are mad.1","tr":"Waqaloo ya ayyuha allatheenuzzila AAalayhi aththikru innaka lamajnoon","juz":14,"page":262},{"s":15,"a":7,"key":"15:7","ar":"لَّوْ مَا تَأْتِينَا بِٱلْمَلَـٰٓئِكَةِ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ","en":"Why do you not bring us the angels, if you should be among the truthful?\"","tr":"Law ma ta/teena bilmala-ikatiin kunta mina assadiqeen","juz":14,"page":262},{"s":15,"a":8,"key":"15:8","ar":"مَا نُنَزِّلُ ٱلْمَلَـٰٓئِكَةَ إِلَّا بِٱلْحَقِّ وَمَا كَانُوٓا۟ إِذًا مُّنظَرِينَ","en":"We do not send down the angels except with truth;1 and they [i.e., the disbelievers] would not then be reprieved.","tr":"Ma nunazzilu almala-ikata illabilhaqqi wama kanoo ithan munthareen","juz":14,"page":262},{"s":15,"a":9,"key":"15:9","ar":"إِنَّا نَحْنُ نَزَّلْنَا ٱلذِّكْرَ وَإِنَّا لَهُۥ لَحَـٰفِظُونَ","en":"Indeed, it is We who sent down the message [i.e., the Qur’ān], and indeed, We will be its guardian.","tr":"Inna nahnu nazzalna aththikrawa-inna lahu lahafithoon","juz":14,"page":262},{"s":15,"a":10,"key":"15:10","ar":"وَلَقَدْ أَرْسَلْنَا مِن قَبْلِكَ فِى شِيَعِ ٱلْأَوَّلِينَ","en":"And We had certainly sent [messengers] before you, [O Muḥammad], among the sects of the former peoples.","tr":"Walaqad arsalna min qablika feeshiyaAAi al-awwaleen","juz":14,"page":262},{"s":15,"a":11,"key":"15:11","ar":"وَمَا يَأْتِيهِم مِّن رَّسُولٍ إِلَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"And no messenger would come to them except that they ridiculed him.","tr":"Wama ya/teehim min rasoolin illakanoo bihi yastahzi-oon","juz":14,"page":262},{"s":15,"a":12,"key":"15:12","ar":"كَذَٰلِكَ نَسْلُكُهُۥ فِى قُلُوبِ ٱلْمُجْرِمِينَ","en":"Thus do We insert it [i.e., denial] into the hearts of the criminals.","tr":"Kathalika naslukuhu fee quloobialmujrimeen","juz":14,"page":262},{"s":15,"a":13,"key":"15:13","ar":"لَا يُؤْمِنُونَ بِهِۦ ۖ وَقَدْ خَلَتْ سُنَّةُ ٱلْأَوَّلِينَ","en":"They will not believe in it, while there has already occurred the precedent of the former peoples.","tr":"La yu/minoona bihi waqad khalatsunnatu al-awwaleen","juz":14,"page":262},{"s":15,"a":14,"key":"15:14","ar":"وَلَوْ فَتَحْنَا عَلَيْهِم بَابًا مِّنَ ٱلسَّمَآءِ فَظَلُّوا۟ فِيهِ يَعْرُجُونَ","en":"And [even] if We opened to them a gate from the heaven and they continued therein to ascend,","tr":"Walaw fatahna AAalayhim babanmina assama-i fathalloo feehiyaAArujoon","juz":14,"page":262},{"s":15,"a":15,"key":"15:15","ar":"لَقَالُوٓا۟ إِنَّمَا سُكِّرَتْ أَبْصَـٰرُنَا بَلْ نَحْنُ قَوْمٌ مَّسْحُورُونَ","en":"They would say, \"Our eyes have only been dazzled. Rather, we are a people affected by magic.\"","tr":"Laqaloo innama sukkirat absarunabal nahnu qawmun mashooroon","juz":14,"page":262},{"s":15,"a":16,"key":"15:16","ar":"وَلَقَدْ جَعَلْنَا فِى ٱلسَّمَآءِ بُرُوجًا وَزَيَّنَّـٰهَا لِلنَّـٰظِرِينَ","en":"And We have placed within the heaven great stars and have beautified it for the observers.","tr":"Walaqad jaAAalna fee assama-iburoojan wazayyannaha linnathireen","juz":14,"page":263},{"s":15,"a":17,"key":"15:17","ar":"وَحَفِظْنَـٰهَا مِن كُلِّ شَيْطَـٰنٍ رَّجِيمٍ","en":"And We have protected it from every devil expelled [from the mercy of Allāh]","tr":"Wahafithnahamin kulli shaytanin rajeem","juz":14,"page":263},{"s":15,"a":18,"key":"15:18","ar":"إِلَّا مَنِ ٱسْتَرَقَ ٱلسَّمْعَ فَأَتْبَعَهُۥ شِهَابٌ مُّبِينٌ","en":"Except one who steals a hearing and is pursued by a clear burning flame.","tr":"Illa mani istaraqa assamAAafaatbaAAahu shihabun mubeen","juz":14,"page":263},{"s":15,"a":19,"key":"15:19","ar":"وَٱلْأَرْضَ مَدَدْنَـٰهَا وَأَلْقَيْنَا فِيهَا رَوَٰسِىَ وَأَنۢبَتْنَا فِيهَا مِن كُلِّ شَىْءٍ مَّوْزُونٍ","en":"And the earth - We have spread it and cast therein firmly set mountains and caused to grow therein [something] of every well-balanced thing.","tr":"Wal-arda madadnahawaalqayna feeha rawasiya waanbatnafeeha min kulli shay-in mawzoon","juz":14,"page":263},{"s":15,"a":20,"key":"15:20","ar":"وَجَعَلْنَا لَكُمْ فِيهَا مَعَـٰيِشَ وَمَن لَّسْتُمْ لَهُۥ بِرَٰزِقِينَ","en":"And We have made for you therein means of living and [for] those for whom you are not providers.1","tr":"WajaAAalna lakum feeha maAAayishawaman lastum lahu biraziqeen","juz":14,"page":263},{"s":15,"a":21,"key":"15:21","ar":"وَإِن مِّن شَىْءٍ إِلَّا عِندَنَا خَزَآئِنُهُۥ وَمَا نُنَزِّلُهُۥٓ إِلَّا بِقَدَرٍ مَّعْلُومٍ","en":"And there is not a thing but that with Us are its depositories, and We do not send it down except according to a known [i.e., specified] measure.","tr":"Wa-in min shay-in illa AAindanakhaza-inuhu wama nunazziluhu illa biqadarinmaAAloom","juz":14,"page":263},{"s":15,"a":22,"key":"15:22","ar":"وَأَرْسَلْنَا ٱلرِّيَـٰحَ لَوَٰقِحَ فَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءً فَأَسْقَيْنَـٰكُمُوهُ وَمَآ أَنتُمْ لَهُۥ بِخَـٰزِنِينَ","en":"And We have sent the fertilizing winds1 and sent down water from the sky and given you drink from it. And you are not its retainers.","tr":"Waarsalna arriyaha lawaqihafaanzalna mina assama-i maanfaasqaynakumoohu wama antum lahu bikhazineen","juz":14,"page":263},{"s":15,"a":23,"key":"15:23","ar":"وَإِنَّا لَنَحْنُ نُحْىِۦ وَنُمِيتُ وَنَحْنُ ٱلْوَٰرِثُونَ","en":"And indeed, it is We who give life and cause death, and We are the Inheritor.1","tr":"Wa-inna lanahnu nuhyeewanumeetu wanahnu alwarithoon","juz":14,"page":263},{"s":15,"a":24,"key":"15:24","ar":"وَلَقَدْ عَلِمْنَا ٱلْمُسْتَقْدِمِينَ مِنكُمْ وَلَقَدْ عَلِمْنَا ٱلْمُسْتَـْٔخِرِينَ","en":"And We have already known the preceding [generations] among you, and We have already known the later [ones to come].","tr":"Walaqad AAalimna almustaqdimeenaminkum walaqad AAalimna almusta/khireen","juz":14,"page":263},{"s":15,"a":25,"key":"15:25","ar":"وَإِنَّ رَبَّكَ هُوَ يَحْشُرُهُمْ ۚ إِنَّهُۥ حَكِيمٌ عَلِيمٌ","en":"And indeed, your Lord will gather them; indeed, He is Wise and Knowing.","tr":"Wa-inna rabbaka huwa yahshuruhuminnahu hakeemun AAaleem","juz":14,"page":263},{"s":15,"a":26,"key":"15:26","ar":"وَلَقَدْ خَلَقْنَا ٱلْإِنسَـٰنَ مِن صَلْصَـٰلٍ مِّنْ حَمَإٍ مَّسْنُونٍ","en":"And We did certainly create man out of clay from an altered black mud.","tr":"Walaqad khalaqna al-insana minsalsalin min hama-in masnoon","juz":14,"page":263},{"s":15,"a":27,"key":"15:27","ar":"وَٱلْجَآنَّ خَلَقْنَـٰهُ مِن قَبْلُ مِن نَّارِ ٱلسَّمُومِ","en":"And the jinn We created before from scorching fire.","tr":"Waljanna khalaqnahumin qablu min nari assamoom","juz":14,"page":263},{"s":15,"a":28,"key":"15:28","ar":"وَإِذْ قَالَ رَبُّكَ لِلْمَلَـٰٓئِكَةِ إِنِّى خَـٰلِقٌۢ بَشَرًا مِّن صَلْصَـٰلٍ مِّنْ حَمَإٍ مَّسْنُونٍ","en":"And [mention, O Muḥammad], when your Lord said to the angels, \"I will create a human being out of clay from an altered black mud.","tr":"Wa-ith qala rabbuka lilmala-ikatiinnee khaliqun basharan min salsalin min hama-inmasnoon","juz":14,"page":263},{"s":15,"a":29,"key":"15:29","ar":"فَإِذَا سَوَّيْتُهُۥ وَنَفَخْتُ فِيهِ مِن رُّوحِى فَقَعُوا۟ لَهُۥ سَـٰجِدِينَ","en":"And when I have proportioned him and breathed into him of My [created] soul,1 then fall down to him in prostration.\"","tr":"Fa-itha sawwaytuhu wanafakhtu feehimin roohee faqaAAoo lahu sajideen","juz":14,"page":263},{"s":15,"a":30,"key":"15:30","ar":"فَسَجَدَ ٱلْمَلَـٰٓئِكَةُ كُلُّهُمْ أَجْمَعُونَ","en":"So the angels prostrated - all of them entirely,","tr":"Fasajada almala-ikatu kulluhumajmaAAoon","juz":14,"page":263},{"s":15,"a":31,"key":"15:31","ar":"إِلَّآ إِبْلِيسَ أَبَىٰٓ أَن يَكُونَ مَعَ ٱلسَّـٰجِدِينَ","en":"Except Iblees;1 he refused to be with those who prostrated.","tr":"Illa ibleesa aba an yakoonamaAAa assajideen","juz":14,"page":263},{"s":15,"a":32,"key":"15:32","ar":"قَالَ يَـٰٓإِبْلِيسُ مَا لَكَ أَلَّا تَكُونَ مَعَ ٱلسَّـٰجِدِينَ","en":"[Allāh] said, \"O Iblees, what is [the matter] with you that you are not with those who prostrate?\"","tr":"Qala ya ibleesu ma lakaalla takoona maAAa assajideen","juz":14,"page":264},{"s":15,"a":33,"key":"15:33","ar":"قَالَ لَمْ أَكُن لِّأَسْجُدَ لِبَشَرٍ خَلَقْتَهُۥ مِن صَلْصَـٰلٍ مِّنْ حَمَإٍ مَّسْنُونٍ","en":"He said, \"Never would I prostrate to a human whom You created out of clay from an altered black mud.\"","tr":"Qala lam akun li-asjuda libasharinkhalaqtahu min salsalin min hama-in masnoon","juz":14,"page":264},{"s":15,"a":34,"key":"15:34","ar":"قَالَ فَٱخْرُجْ مِنْهَا فَإِنَّكَ رَجِيمٌ","en":"[Allāh] said, \"Then depart from it,1 for indeed, you are expelled.","tr":"Qala fakhruj minhafa-innaka rajeem","juz":14,"page":264},{"s":15,"a":35,"key":"15:35","ar":"وَإِنَّ عَلَيْكَ ٱللَّعْنَةَ إِلَىٰ يَوْمِ ٱلدِّينِ","en":"And indeed, upon you is the curse until the Day of Recompense.\"","tr":"Wa-inna AAalayka allaAAnata ila yawmiaddeen","juz":14,"page":264},{"s":15,"a":36,"key":"15:36","ar":"قَالَ رَبِّ فَأَنظِرْنِىٓ إِلَىٰ يَوْمِ يُبْعَثُونَ","en":"He said, \"My Lord, then reprieve me until the Day they are resurrected.\"","tr":"Qala rabbi faanthirneeila yawmi yubAAathoon","juz":14,"page":264},{"s":15,"a":37,"key":"15:37","ar":"قَالَ فَإِنَّكَ مِنَ ٱلْمُنظَرِينَ","en":"[Allāh] said, \"So indeed, you are of those reprieved","tr":"Qala fa-innaka mina almunthareen","juz":14,"page":264},{"s":15,"a":38,"key":"15:38","ar":"إِلَىٰ يَوْمِ ٱلْوَقْتِ ٱلْمَعْلُومِ","en":"Until the Day of the time well-known.\"","tr":"Ila yawmi alwaqti almaAAloom","juz":14,"page":264},{"s":15,"a":39,"key":"15:39","ar":"قَالَ رَبِّ بِمَآ أَغْوَيْتَنِى لَأُزَيِّنَنَّ لَهُمْ فِى ٱلْأَرْضِ وَلَأُغْوِيَنَّهُمْ أَجْمَعِينَ","en":"[Iblees] said, \"My Lord, because You have put me in error, I will surely make [disobedience] attractive to them [i.e., mankind] on earth, and I will mislead them all","tr":"Qala rabbi bima aghwaytaneelaozayyinanna lahum fee al-ardi walaoghwiyannahumajmaAAeen","juz":14,"page":264},{"s":15,"a":40,"key":"15:40","ar":"إِلَّا عِبَادَكَ مِنْهُمُ ٱلْمُخْلَصِينَ","en":"Except, among them, Your chosen servants.\"","tr":"Illa AAibadaka minhumualmukhlaseen","juz":14,"page":264},{"s":15,"a":41,"key":"15:41","ar":"قَالَ هَـٰذَا صِرَٰطٌ عَلَىَّ مُسْتَقِيمٌ","en":"[Allāh] said, \"This is a path [of return] to Me [that is] straight.","tr":"Qala hatha siratunAAalayya mustaqeem","juz":14,"page":264},{"s":15,"a":42,"key":"15:42","ar":"إِنَّ عِبَادِى لَيْسَ لَكَ عَلَيْهِمْ سُلْطَـٰنٌ إِلَّا مَنِ ٱتَّبَعَكَ مِنَ ٱلْغَاوِينَ","en":"Indeed, My servants - no authority will you have over them, except those who follow you of the deviators.","tr":"Inna AAibadee laysa laka AAalayhimsultanun illa mani ittabaAAaka mina alghaween","juz":14,"page":264},{"s":15,"a":43,"key":"15:43","ar":"وَإِنَّ جَهَنَّمَ لَمَوْعِدُهُمْ أَجْمَعِينَ","en":"And indeed, Hell is the promised place for them all.","tr":"Wa-inna jahannama lamawAAiduhum ajmaAAeen","juz":14,"page":264},{"s":15,"a":44,"key":"15:44","ar":"لَهَا سَبْعَةُ أَبْوَٰبٍ لِّكُلِّ بَابٍ مِّنْهُمْ جُزْءٌ مَّقْسُومٌ","en":"It has seven gates; for every gate is of them [i.e., Satan's followers] a portion designated.\"","tr":"Laha sabAAatu abwabin likullibabin minhum juz-on maqsoom","juz":14,"page":264},{"s":15,"a":45,"key":"15:45","ar":"إِنَّ ٱلْمُتَّقِينَ فِى جَنَّـٰتٍ وَعُيُونٍ","en":"Indeed, the righteous will be within gardens and springs,","tr":"Inna almuttaqeena fee jannatinwaAAuyoon","juz":14,"page":264},{"s":15,"a":46,"key":"15:46","ar":"ٱدْخُلُوهَا بِسَلَـٰمٍ ءَامِنِينَ","en":"[Having been told], \"Enter it in peace, safe [and secure].\"","tr":"Odkhulooha bisalamin amineen","juz":14,"page":264},{"s":15,"a":47,"key":"15:47","ar":"وَنَزَعْنَا مَا فِى صُدُورِهِم مِّنْ غِلٍّ إِخْوَٰنًا عَلَىٰ سُرُرٍ مُّتَقَـٰبِلِينَ","en":"And We will remove whatever is in their breasts of resentment,1 [so they will be] brothers, on thrones facing each other.","tr":"WanazaAAna ma fee sudoorihimmin ghillin ikhwanan AAala sururin mutaqabileen","juz":14,"page":264},{"s":15,"a":48,"key":"15:48","ar":"لَا يَمَسُّهُمْ فِيهَا نَصَبٌ وَمَا هُم مِّنْهَا بِمُخْرَجِينَ","en":"No fatigue will touch them therein, nor from it will they [ever] be removed.","tr":"La yamassuhum feeha nasabunwama hum minha bimukhrajeen","juz":14,"page":264},{"s":15,"a":49,"key":"15:49","ar":"۞ نَبِّئْ عِبَادِىٓ أَنِّىٓ أَنَا ٱلْغَفُورُ ٱلرَّحِيمُ","en":"[O Muḥammad], inform My servants that it is I who am the Forgiving, the Merciful,","tr":"Nabbi/ AAibadee annee anaalghafooru arraheem","juz":14,"page":264},{"s":15,"a":50,"key":"15:50","ar":"وَأَنَّ عَذَابِى هُوَ ٱلْعَذَابُ ٱلْأَلِيمُ","en":"And that it is My punishment which is the painful punishment.","tr":"Waanna AAathabee huwa alAAathabual-aleem","juz":14,"page":264},{"s":15,"a":51,"key":"15:51","ar":"وَنَبِّئْهُمْ عَن ضَيْفِ إِبْرَٰهِيمَ","en":"And inform them about the guests of Abraham,","tr":"Wanabbi/hum AAan dayfi ibraheem","juz":14,"page":264},{"s":15,"a":52,"key":"15:52","ar":"إِذْ دَخَلُوا۟ عَلَيْهِ فَقَالُوا۟ سَلَـٰمًا قَالَ إِنَّا مِنكُمْ وَجِلُونَ","en":"When they entered upon him and said, \"Peace.\" [Abraham] said, \"Indeed, we are fearful [i.e., apprehensive] of you.\"","tr":"Ith dakhaloo AAalayhi faqaloosalaman qala inna minkum wajiloon","juz":14,"page":265},{"s":15,"a":53,"key":"15:53","ar":"قَالُوا۟ لَا تَوْجَلْ إِنَّا نُبَشِّرُكَ بِغُلَـٰمٍ عَلِيمٍ","en":"[The angels] said, \"Fear not. Indeed, we give you good tidings of a learned boy.\"","tr":"Qaloo la tawjal innanubashshiruka bighulamin AAaleem","juz":14,"page":265},{"s":15,"a":54,"key":"15:54","ar":"قَالَ أَبَشَّرْتُمُونِى عَلَىٰٓ أَن مَّسَّنِىَ ٱلْكِبَرُ فَبِمَ تُبَشِّرُونَ","en":"He said, \"Have you given me good tidings although old age has come upon me? Then of what [wonder] do you inform?\"","tr":"Qala abashshartumoonee AAalaan massaniya alkibaru fabima tubashshiroon","juz":14,"page":265},{"s":15,"a":55,"key":"15:55","ar":"قَالُوا۟ بَشَّرْنَـٰكَ بِٱلْحَقِّ فَلَا تَكُن مِّنَ ٱلْقَـٰنِطِينَ","en":"They said, \"We have given you good tidings in truth, so do not be of the despairing.\"","tr":"Qaloo bashsharnaka bilhaqqifala takun mina alqaniteen","juz":14,"page":265},{"s":15,"a":56,"key":"15:56","ar":"قَالَ وَمَن يَقْنَطُ مِن رَّحْمَةِ رَبِّهِۦٓ إِلَّا ٱلضَّآلُّونَ","en":"He said, \"And who despairs of the mercy of his Lord except for those astray?\"","tr":"Qala waman yaqnatu min rahmatirabbihi illa addalloon","juz":14,"page":265},{"s":15,"a":57,"key":"15:57","ar":"قَالَ فَمَا خَطْبُكُمْ أَيُّهَا ٱلْمُرْسَلُونَ","en":"[Abraham] said, \"Then what is your business [here], O messengers?\"","tr":"Qala fama khatbukumayyuha almursaloon","juz":14,"page":265},{"s":15,"a":58,"key":"15:58","ar":"قَالُوٓا۟ إِنَّآ أُرْسِلْنَآ إِلَىٰ قَوْمٍ مُّجْرِمِينَ","en":"They said, \"Indeed, we have been sent to a people of criminals,","tr":"Qaloo inna orsilna ilaqawmin mujrimeen","juz":14,"page":265},{"s":15,"a":59,"key":"15:59","ar":"إِلَّآ ءَالَ لُوطٍ إِنَّا لَمُنَجُّوهُمْ أَجْمَعِينَ","en":"Except the family of Lot; indeed, we will save them all","tr":"Illa ala lootin innalamunajjoohum ajmaAAeen","juz":14,"page":265},{"s":15,"a":60,"key":"15:60","ar":"إِلَّا ٱمْرَأَتَهُۥ قَدَّرْنَآ ۙ إِنَّهَا لَمِنَ ٱلْغَـٰبِرِينَ","en":"Except his wife.\" We [i.e., Allāh] decreed that she is of those who remain behind.1","tr":"Illa imraatahu qaddarna innahalamina alghabireen","juz":14,"page":265},{"s":15,"a":61,"key":"15:61","ar":"فَلَمَّا جَآءَ ءَالَ لُوطٍ ٱلْمُرْسَلُونَ","en":"And when the messengers came to the family of Lot,","tr":"Falamma jaa ala lootinalmursaloon","juz":14,"page":265},{"s":15,"a":62,"key":"15:62","ar":"قَالَ إِنَّكُمْ قَوْمٌ مُّنكَرُونَ","en":"He said, \"Indeed, you are people unknown.\"","tr":"Qala innakum qawmun munkaroon","juz":14,"page":265},{"s":15,"a":63,"key":"15:63","ar":"قَالُوا۟ بَلْ جِئْنَـٰكَ بِمَا كَانُوا۟ فِيهِ يَمْتَرُونَ","en":"They said, \"But we have come to you with that about which they were disputing,","tr":"Qaloo bal ji/naka bimakanoo feehi yamtaroon","juz":14,"page":265},{"s":15,"a":64,"key":"15:64","ar":"وَأَتَيْنَـٰكَ بِٱلْحَقِّ وَإِنَّا لَصَـٰدِقُونَ","en":"And we have come to you with truth, and indeed, we are truthful.","tr":"Waataynaka bilhaqqiwa-inna lasadiqoon","juz":14,"page":265},{"s":15,"a":65,"key":"15:65","ar":"فَأَسْرِ بِأَهْلِكَ بِقِطْعٍ مِّنَ ٱلَّيْلِ وَٱتَّبِعْ أَدْبَـٰرَهُمْ وَلَا يَلْتَفِتْ مِنكُمْ أَحَدٌ وَٱمْضُوا۟ حَيْثُ تُؤْمَرُونَ","en":"So set out with your family during a portion of the night and follow behind them and let not anyone among you look back and continue on to where you are commanded.\"","tr":"Faasri bi-ahlika biqitAAin minaallayli wattabiAA adbarahum wala yaltafitminkum ahadun wamdoo haythutu/maroon","juz":14,"page":265},{"s":15,"a":66,"key":"15:66","ar":"وَقَضَيْنَآ إِلَيْهِ ذَٰلِكَ ٱلْأَمْرَ أَنَّ دَابِرَ هَـٰٓؤُلَآءِ مَقْطُوعٌ مُّصْبِحِينَ","en":"And We conveyed to him [the decree] of that matter: that those [sinners] would be eliminated by early morning.","tr":"Waqadayna ilayhi thalikaal-amra anna dabira haola-i maqtooAAunmusbiheen","juz":14,"page":265},{"s":15,"a":67,"key":"15:67","ar":"وَجَآءَ أَهْلُ ٱلْمَدِينَةِ يَسْتَبْشِرُونَ","en":"And the people of the city came rejoicing.1","tr":"Wajaa ahlu almadeenati yastabshiroon","juz":14,"page":265},{"s":15,"a":68,"key":"15:68","ar":"قَالَ إِنَّ هَـٰٓؤُلَآءِ ضَيْفِى فَلَا تَفْضَحُونِ","en":"[Lot] said, \"Indeed, these are my guests, so do not shame me.","tr":"Qala inna haola-i dayfeefala tafdahoon","juz":14,"page":265},{"s":15,"a":69,"key":"15:69","ar":"وَٱتَّقُوا۟ ٱللَّهَ وَلَا تُخْزُونِ","en":"And fear Allāh and do not disgrace me.\"","tr":"Wattaqoo Allaha walatukhzoon","juz":14,"page":265},{"s":15,"a":70,"key":"15:70","ar":"قَالُوٓا۟ أَوَلَمْ نَنْهَكَ عَنِ ٱلْعَـٰلَمِينَ","en":"They said, \"Have we not forbidden you from [protecting] people?\"","tr":"Qaloo awa lam nanhaka AAani alAAalameen","juz":14,"page":265},{"s":15,"a":71,"key":"15:71","ar":"قَالَ هَـٰٓؤُلَآءِ بَنَاتِىٓ إِن كُنتُمْ فَـٰعِلِينَ","en":"[Lot] said, \"These are my daughters1 - if you would be doers [of lawful marriage].\"","tr":"Qala haola-i banateein kuntum faAAileen","juz":14,"page":266},{"s":15,"a":72,"key":"15:72","ar":"لَعَمْرُكَ إِنَّهُمْ لَفِى سَكْرَتِهِمْ يَعْمَهُونَ","en":"By your life, [O Muḥammad], indeed they were, in their intoxication, wandering blindly.","tr":"LaAAamruka innahum lafee sakratihimyaAAmahoona","juz":14,"page":266},{"s":15,"a":73,"key":"15:73","ar":"فَأَخَذَتْهُمُ ٱلصَّيْحَةُ مُشْرِقِينَ","en":"So the shriek1 seized them at sunrise.","tr":"Faakhathat-humu assayhatumushriqeen","juz":14,"page":266},{"s":15,"a":74,"key":"15:74","ar":"فَجَعَلْنَا عَـٰلِيَهَا سَافِلَهَا وَأَمْطَرْنَا عَلَيْهِمْ حِجَارَةً مِّن سِجِّيلٍ","en":"And We made the highest part [of the city] its lowest and rained upon them stones of hard clay.","tr":"FajaAAalna AAaliyaha safilahawaamtarna AAalayhim hijaratan minsijjeel","juz":14,"page":266},{"s":15,"a":75,"key":"15:75","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّلْمُتَوَسِّمِينَ","en":"Indeed in that are signs for those who discern.","tr":"Inna fee thalika laayatinlilmutawassimeen","juz":14,"page":266},{"s":15,"a":76,"key":"15:76","ar":"وَإِنَّهَا لَبِسَبِيلٍ مُّقِيمٍ","en":"And indeed, they [i.e., those cities] are [situated] on an established road.","tr":"Wa-innaha labisabeelin muqeem","juz":14,"page":266},{"s":15,"a":77,"key":"15:77","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّلْمُؤْمِنِينَ","en":"Indeed in that is a sign for the believers.","tr":"Inna fee thalika laayatanlilmu/mineen","juz":14,"page":266},{"s":15,"a":78,"key":"15:78","ar":"وَإِن كَانَ أَصْحَـٰبُ ٱلْأَيْكَةِ لَظَـٰلِمِينَ","en":"And the companions of the thicket [i.e., the people of Madyan] were [also] wrongdoers,","tr":"Wa-in kana as-habual-aykati lathalimeen","juz":14,"page":266},{"s":15,"a":79,"key":"15:79","ar":"فَٱنتَقَمْنَا مِنْهُمْ وَإِنَّهُمَا لَبِإِمَامٍ مُّبِينٍ","en":"So We took retribution from them, and indeed, both [cities] are on a clear highway.","tr":"Fantaqamna minhum wa-innahumalabi-imamin mubeen","juz":14,"page":266},{"s":15,"a":80,"key":"15:80","ar":"وَلَقَدْ كَذَّبَ أَصْحَـٰبُ ٱلْحِجْرِ ٱلْمُرْسَلِينَ","en":"And certainly did the companions of al-Ḥijr1 [i.e., the Thamūd] deny the messengers.","tr":"Walaqad kaththaba as-habualhijri almursaleen","juz":14,"page":266},{"s":15,"a":81,"key":"15:81","ar":"وَءَاتَيْنَـٰهُمْ ءَايَـٰتِنَا فَكَانُوا۟ عَنْهَا مُعْرِضِينَ","en":"And We gave them Our signs, but from them they were turning away.","tr":"Waataynahum ayatinafakanoo AAanha muAArideen","juz":14,"page":266},{"s":15,"a":82,"key":"15:82","ar":"وَكَانُوا۟ يَنْحِتُونَ مِنَ ٱلْجِبَالِ بُيُوتًا ءَامِنِينَ","en":"And they used to carve from the mountains, houses, feeling secure.","tr":"Wakanoo yanhitoona mina aljibalibuyootan amineen","juz":14,"page":266},{"s":15,"a":83,"key":"15:83","ar":"فَأَخَذَتْهُمُ ٱلصَّيْحَةُ مُصْبِحِينَ","en":"But the shriek seized them at early morning,","tr":"Faakhathat-humu assayhatumusbiheen","juz":14,"page":266},{"s":15,"a":84,"key":"15:84","ar":"فَمَآ أَغْنَىٰ عَنْهُم مَّا كَانُوا۟ يَكْسِبُونَ","en":"So nothing availed them [from] what they used to earn.","tr":"Fama aghna AAanhum ma kanooyaksiboon","juz":14,"page":266},{"s":15,"a":85,"key":"15:85","ar":"وَمَا خَلَقْنَا ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَآ إِلَّا بِٱلْحَقِّ ۗ وَإِنَّ ٱلسَّاعَةَ لَـَٔاتِيَةٌ ۖ فَٱصْفَحِ ٱلصَّفْحَ ٱلْجَمِيلَ","en":"And We have not created the heavens and earth and that between them except in truth. And indeed, the Hour is coming; so forgive with gracious forgiveness.","tr":"Wama khalaqna assamawatiwal-arda wama baynahuma illabilhaqqi wa-inna assaAAata laatiyatunfasfahi assafhaaljameel","juz":14,"page":266},{"s":15,"a":86,"key":"15:86","ar":"إِنَّ رَبَّكَ هُوَ ٱلْخَلَّـٰقُ ٱلْعَلِيمُ","en":"Indeed, your Lord - He is the Knowing Creator.","tr":"Inna rabbaka huwa alkhallaqualAAaleem","juz":14,"page":266},{"s":15,"a":87,"key":"15:87","ar":"وَلَقَدْ ءَاتَيْنَـٰكَ سَبْعًا مِّنَ ٱلْمَثَانِى وَٱلْقُرْءَانَ ٱلْعَظِيمَ","en":"And We have certainly given you, [O Muḥammad], seven of the often repeated [verses]1 and the great Qur’ān.","tr":"Walaqad ataynaka sabAAan minaalmathanee walqur-ana alAAatheem","juz":14,"page":266},{"s":15,"a":88,"key":"15:88","ar":"لَا تَمُدَّنَّ عَيْنَيْكَ إِلَىٰ مَا مَتَّعْنَا بِهِۦٓ أَزْوَٰجًا مِّنْهُمْ وَلَا تَحْزَنْ عَلَيْهِمْ وَٱخْفِضْ جَنَاحَكَ لِلْمُؤْمِنِينَ","en":"Do not extend your eyes toward that by which We have given enjoyment to [certain] categories of them [i.e., the disbelievers], and do not grieve over them. And lower your wing [i.e., show kindness] to the believers.","tr":"La tamuddanna AAaynayka ila mamattaAAna bihi azwajan minhum wala tahzanAAalayhim wakhfid janahaka lilmu/mineen","juz":14,"page":266},{"s":15,"a":89,"key":"15:89","ar":"وَقُلْ إِنِّىٓ أَنَا ٱلنَّذِيرُ ٱلْمُبِينُ","en":"And say, \"Indeed, I am the clear warner\" -","tr":"Waqul innee ana annatheerualmubeen","juz":14,"page":266},{"s":15,"a":90,"key":"15:90","ar":"كَمَآ أَنزَلْنَا عَلَى ٱلْمُقْتَسِمِينَ","en":"Just as We had revealed [scriptures] to the separators1","tr":"Kama anzalna AAalaalmuqtasimeen","juz":14,"page":266},{"s":15,"a":91,"key":"15:91","ar":"ٱلَّذِينَ جَعَلُوا۟ ٱلْقُرْءَانَ عِضِينَ","en":"Who have made the Qur’ān into portions.1","tr":"Allatheena jaAAaloo alqur-anaAAideen","juz":14,"page":267},{"s":15,"a":92,"key":"15:92","ar":"فَوَرَبِّكَ لَنَسْـَٔلَنَّهُمْ أَجْمَعِينَ","en":"So by your Lord, We will surely question them all","tr":"Fawarabbika lanas-alannahum ajmaAAeen","juz":14,"page":267},{"s":15,"a":93,"key":"15:93","ar":"عَمَّا كَانُوا۟ يَعْمَلُونَ","en":"About what they used to do.","tr":"AAamma kanoo yaAAmaloon","juz":14,"page":267},{"s":15,"a":94,"key":"15:94","ar":"فَٱصْدَعْ بِمَا تُؤْمَرُ وَأَعْرِضْ عَنِ ٱلْمُشْرِكِينَ","en":"Then declare what you are commanded1 and turn away from the polytheists.2","tr":"FasdaAA bima tu/maruwaaAArid AAani almushrikeen","juz":14,"page":267},{"s":15,"a":95,"key":"15:95","ar":"إِنَّا كَفَيْنَـٰكَ ٱلْمُسْتَهْزِءِينَ","en":"Indeed, We are sufficient for you against the mockers","tr":"Inna kafaynaka almustahzi-een","juz":14,"page":267},{"s":15,"a":96,"key":"15:96","ar":"ٱلَّذِينَ يَجْعَلُونَ مَعَ ٱللَّهِ إِلَـٰهًا ءَاخَرَ ۚ فَسَوْفَ يَعْلَمُونَ","en":"Who make [equal] with Allāh another deity. But they are going to know.","tr":"Allatheena yajAAaloona maAAa Allahiilahan akhara fasawfa yaAAlamoon","juz":14,"page":267},{"s":15,"a":97,"key":"15:97","ar":"وَلَقَدْ نَعْلَمُ أَنَّكَ يَضِيقُ صَدْرُكَ بِمَا يَقُولُونَ","en":"And We already know that your breast is constrained by what they say.","tr":"Walaqad naAAlamu annaka yadeequ sadrukabima yaqooloon","juz":14,"page":267},{"s":15,"a":98,"key":"15:98","ar":"فَسَبِّحْ بِحَمْدِ رَبِّكَ وَكُن مِّنَ ٱلسَّـٰجِدِينَ","en":"So exalt [Allāh] with praise of your Lord and be of those who prostrate [to Him].","tr":"Fasabbih bihamdi rabbika wakunmina assajideen","juz":14,"page":267},{"s":15,"a":99,"key":"15:99","ar":"وَٱعْبُدْ رَبَّكَ حَتَّىٰ يَأْتِيَكَ ٱلْيَقِينُ","en":"And worship your Lord until there comes to you the certainty [i.e., death].","tr":"WaAAbud rabbaka hattaya/tiyaka alyaqeen","juz":14,"page":267},{"s":16,"a":1,"key":"16:1","ar":" أَتَىٰٓ أَمْرُ ٱللَّهِ فَلَا تَسْتَعْجِلُوهُ ۚ سُبْحَـٰنَهُۥ وَتَعَـٰلَىٰ عَمَّا يُشْرِكُونَ","en":"The command of Allāh is coming,1 so be not impatient for it. Exalted is He and high above what they associate with Him.","tr":"Ata amru Allahi falatastaAAjiloohu subhanahu wataAAala AAammayushrikoon","juz":14,"page":267},{"s":16,"a":2,"key":"16:2","ar":"يُنَزِّلُ ٱلْمَلَـٰٓئِكَةَ بِٱلرُّوحِ مِنْ أَمْرِهِۦ عَلَىٰ مَن يَشَآءُ مِنْ عِبَادِهِۦٓ أَنْ أَنذِرُوٓا۟ أَنَّهُۥ لَآ إِلَـٰهَ إِلَّآ أَنَا۠ فَٱتَّقُونِ","en":"He sends down the angels, with the inspiration [i.e., revelation] of His command, upon whom He wills of His servants, [telling them], \"Warn that there is no deity except Me; so fear Me.\"","tr":"Yunazzilu almala-ikata birroohimin amrihi AAala man yashao min AAibadihi ananthiroo annahu la ilaha illa anafattaqoon","juz":14,"page":267},{"s":16,"a":3,"key":"16:3","ar":"خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۚ تَعَـٰلَىٰ عَمَّا يُشْرِكُونَ","en":"He created the heavens and earth in truth. High is He above what they associate with Him.","tr":"Khalaqa assamawati wal-ardabilhaqqi taAAala AAammayushrikoon","juz":14,"page":267},{"s":16,"a":4,"key":"16:4","ar":"خَلَقَ ٱلْإِنسَـٰنَ مِن نُّطْفَةٍ فَإِذَا هُوَ خَصِيمٌ مُّبِينٌ","en":"He created man from a sperm-drop; then at once1 he is a clear adversary.","tr":"Khalaqa al-insana min nutfatinfa-itha huwa khaseemun mubeen","juz":14,"page":267},{"s":16,"a":5,"key":"16:5","ar":"وَٱلْأَنْعَـٰمَ خَلَقَهَا ۗ لَكُمْ فِيهَا دِفْءٌ وَمَنَـٰفِعُ وَمِنْهَا تَأْكُلُونَ","en":"And the grazing livestock He has created for you; in them is warmth1 and [numerous] benefits, and from them you eat.","tr":"Wal-anAAama khalaqahalakum feeha dif-on wamanafiAAu waminhata-kuloon","juz":14,"page":267},{"s":16,"a":6,"key":"16:6","ar":"وَلَكُمْ فِيهَا جَمَالٌ حِينَ تُرِيحُونَ وَحِينَ تَسْرَحُونَ","en":"And for you in them is [the enjoyment of] beauty when you bring them in [for the evening] and when you send them out [to pasture].","tr":"Walakum feeha jamalun heenatureehoona waheena tasrahoon","juz":14,"page":267},{"s":16,"a":7,"key":"16:7","ar":"وَتَحْمِلُ أَثْقَالَكُمْ إِلَىٰ بَلَدٍ لَّمْ تَكُونُوا۟ بَـٰلِغِيهِ إِلَّا بِشِقِّ ٱلْأَنفُسِ ۚ إِنَّ رَبَّكُمْ لَرَءُوفٌ رَّحِيمٌ","en":"And they carry your loads to a land you could not have reached except with difficulty to yourselves. Indeed, your Lord is Kind and Merciful.","tr":"Watahmilu athqalakum ilabaladin lam takoonoo baligheehi illa bishiqqial-anfusi inna rabbakum laraoofun raheem","juz":14,"page":268},{"s":16,"a":8,"key":"16:8","ar":"وَٱلْخَيْلَ وَٱلْبِغَالَ وَٱلْحَمِيرَ لِتَرْكَبُوهَا وَزِينَةً ۚ وَيَخْلُقُ مَا لَا تَعْلَمُونَ","en":"And [He created] the horses, mules and donkeys for you to ride and [as] adornment. And He creates that which you do not know.","tr":"Walkhayla walbighalawalhameera litarkabooha wazeenatanwayakhluqu ma la taAAlamoon","juz":14,"page":268},{"s":16,"a":9,"key":"16:9","ar":"وَعَلَى ٱللَّهِ قَصْدُ ٱلسَّبِيلِ وَمِنْهَا جَآئِرٌ ۚ وَلَوْ شَآءَ لَهَدَىٰكُمْ أَجْمَعِينَ","en":"And upon Allāh1 is the direction of the [right] way, and among them [i.e., the various paths] are those deviating. And if He willed, He could have guided you all.","tr":"WaAAala Allahi qasdu assabeeliwaminha ja-irun walaw shaa lahadakumajmaAAeen","juz":14,"page":268},{"s":16,"a":10,"key":"16:10","ar":"هُوَ ٱلَّذِىٓ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً ۖ لَّكُم مِّنْهُ شَرَابٌ وَمِنْهُ شَجَرٌ فِيهِ تُسِيمُونَ","en":"It is He who sends down rain from the sky; from it is drink and from it is foliage in which you pasture [animals].","tr":"Huwa allathee anzala mina assama-imaan lakum minhu sharabun waminhu shajarun feehituseemoon","juz":14,"page":268},{"s":16,"a":11,"key":"16:11","ar":"يُنۢبِتُ لَكُم بِهِ ٱلزَّرْعَ وَٱلزَّيْتُونَ وَٱلنَّخِيلَ وَٱلْأَعْنَـٰبَ وَمِن كُلِّ ٱلثَّمَرَٰتِ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّقَوْمٍ يَتَفَكَّرُونَ","en":"He causes to grow for you thereby the crops, olives, palm trees, grapevines, and of all the fruits. Indeed in that is a sign for a people who give thought.","tr":"Yunbitu lakum bihi azzarAAa wazzaytoonawannakheela wal-aAAnaba wamin kulli aththamaratiinna fee thalika laayatan liqawmin yatafakkaroon","juz":14,"page":268},{"s":16,"a":12,"key":"16:12","ar":"وَسَخَّرَ لَكُمُ ٱلَّيْلَ وَٱلنَّهَارَ وَٱلشَّمْسَ وَٱلْقَمَرَ ۖ وَٱلنُّجُومُ مُسَخَّرَٰتٌۢ بِأَمْرِهِۦٓ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يَعْقِلُونَ","en":"And He has subjected for you the night and day and the sun and moon, and the stars are subjected by His command. Indeed in that are signs for a people who reason.","tr":"Wasakhkhara lakumu allayla wannaharawashshamsa walqamara wannujoomumusakhkharatun bi-amrihi inna fee thalika laayatinliqawmin yaAAqiloon","juz":14,"page":268},{"s":16,"a":13,"key":"16:13","ar":"وَمَا ذَرَأَ لَكُمْ فِى ٱلْأَرْضِ مُخْتَلِفًا أَلْوَٰنُهُۥٓ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّقَوْمٍ يَذَّكَّرُونَ","en":"And [He has subjected] whatever He multiplied for you on the earth of varying colors. Indeed in that is a sign for a people who remember.","tr":"Wama tharaa lakum fee al-ardimukhtalifan alwanuhu inna fee thalika laayatanliqawmin yaththakkaroon","juz":14,"page":268},{"s":16,"a":14,"key":"16:14","ar":"وَهُوَ ٱلَّذِى سَخَّرَ ٱلْبَحْرَ لِتَأْكُلُوا۟ مِنْهُ لَحْمًا طَرِيًّا وَتَسْتَخْرِجُوا۟ مِنْهُ حِلْيَةً تَلْبَسُونَهَا وَتَرَى ٱلْفُلْكَ مَوَاخِرَ فِيهِ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ","en":"And it is He who subjected the sea for you to eat from it tender meat and to extract from it ornaments which you wear. And you see the ships plowing through it, and [He subjected it] that you may seek of His bounty; and perhaps you will be grateful.","tr":"Wahuwa allathee sakhkhara albahralita/kuloo minhu lahman tariyyan watastakhrijoominhu hilyatan talbasoonaha watara alfulkamawakhira feehi walitabtaghoo min fadlihiwalaAAallakum tashkuroon","juz":14,"page":268},{"s":16,"a":15,"key":"16:15","ar":"وَأَلْقَىٰ فِى ٱلْأَرْضِ رَوَٰسِىَ أَن تَمِيدَ بِكُمْ وَأَنْهَـٰرًا وَسُبُلًا لَّعَلَّكُمْ تَهْتَدُونَ","en":"And He has cast into the earth firmly set mountains, lest it shift with you, and [made] rivers and roads, that you may be guided,","tr":"Waalqa fee al-ardi rawasiyaan tameeda bikum waanharan wasubulan laAAallakum tahtadoon","juz":14,"page":269},{"s":16,"a":16,"key":"16:16","ar":"وَعَلَـٰمَـٰتٍ ۚ وَبِٱلنَّجْمِ هُمْ يَهْتَدُونَ","en":"And landmarks. And by the stars they are [also] guided.1","tr":"WaAAalamatin wabinnajmihum yahtadoon","juz":14,"page":269},{"s":16,"a":17,"key":"16:17","ar":"أَفَمَن يَخْلُقُ كَمَن لَّا يَخْلُقُ ۗ أَفَلَا تَذَكَّرُونَ","en":"Then is He who creates like one who does not create? So will you not be reminded?","tr":"Afaman yakhluqu kaman la yakhluquafala tathakkaroon","juz":14,"page":269},{"s":16,"a":18,"key":"16:18","ar":"وَإِن تَعُدُّوا۟ نِعْمَةَ ٱللَّهِ لَا تُحْصُوهَآ ۗ إِنَّ ٱللَّهَ لَغَفُورٌ رَّحِيمٌ","en":"And if you should count the favors of Allāh, you could not enumerate them. Indeed, Allāh is Forgiving and Merciful.","tr":"Wa-in taAAuddoo niAAmata Allahi latuhsooha inna Allaha laghafoorun raheem","juz":14,"page":269},{"s":16,"a":19,"key":"16:19","ar":"وَٱللَّهُ يَعْلَمُ مَا تُسِرُّونَ وَمَا تُعْلِنُونَ","en":"And Allāh knows what you conceal and what you declare.","tr":"Wallahu yaAAlamu matusirroona wama tuAAlinoon","juz":14,"page":269},{"s":16,"a":20,"key":"16:20","ar":"وَٱلَّذِينَ يَدْعُونَ مِن دُونِ ٱللَّهِ لَا يَخْلُقُونَ شَيْـًٔا وَهُمْ يُخْلَقُونَ","en":"And those they invoke other than Allāh create nothing, and they [themselves] are created.","tr":"Wallatheena yadAAoona mindooni Allahi la yakhluqoona shay-an wahumyukhlaqoon","juz":14,"page":269},{"s":16,"a":21,"key":"16:21","ar":"أَمْوَٰتٌ غَيْرُ أَحْيَآءٍ ۖ وَمَا يَشْعُرُونَ أَيَّانَ يُبْعَثُونَ","en":"They are [in fact] dead,1 not alive, and they do not perceive when they will be resurrected.","tr":"Amwatun ghayru ahya-inwama yashAAuroona ayyana yubAAathoon","juz":14,"page":269},{"s":16,"a":22,"key":"16:22","ar":"إِلَـٰهُكُمْ إِلَـٰهٌ وَٰحِدٌ ۚ فَٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ قُلُوبُهُم مُّنكِرَةٌ وَهُم مُّسْتَكْبِرُونَ","en":"Your god is one God. But those who do not believe in the Hereafter - their hearts are disapproving, and they are arrogant.","tr":"Ilahukum ilahun wahidunfallatheena la yu/minoona bil-akhiratiquloobuhum munkiratun wahum mustakbiroon","juz":14,"page":269},{"s":16,"a":23,"key":"16:23","ar":"لَا جَرَمَ أَنَّ ٱللَّهَ يَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْمُسْتَكْبِرِينَ","en":"Assuredly, Allāh knows what they conceal and what they declare. Indeed, He does not like the arrogant.","tr":"La jarama anna Allaha yaAAlamuma yusirroona wama yuAAlinoona innahu la yuhibbualmustakbireen","juz":14,"page":269},{"s":16,"a":24,"key":"16:24","ar":"وَإِذَا قِيلَ لَهُم مَّاذَآ أَنزَلَ رَبُّكُمْ ۙ قَالُوٓا۟ أَسَـٰطِيرُ ٱلْأَوَّلِينَ","en":"And when it is said to them, \"What has your Lord sent down?\" they say, \"Legends of the former peoples,\"","tr":"Wa-itha qeela lahum mathaanzala rabbukum qaloo asateeru al-awwaleen","juz":14,"page":269},{"s":16,"a":25,"key":"16:25","ar":"لِيَحْمِلُوٓا۟ أَوْزَارَهُمْ كَامِلَةً يَوْمَ ٱلْقِيَـٰمَةِ ۙ وَمِنْ أَوْزَارِ ٱلَّذِينَ يُضِلُّونَهُم بِغَيْرِ عِلْمٍ ۗ أَلَا سَآءَ مَا يَزِرُونَ","en":"That they may bear their own burdens [i.e., sins] in full on the Day of Resurrection and some of the burdens of those whom they misguide without [i.e., by lack of] knowledge. Unquestionably, evil is that which they bear.","tr":"Liyahmiloo awzarahum kamilatanyawma alqiyamati wamin awzari allatheena yudilloonahumbighayri AAilmin ala saa ma yaziroon","juz":14,"page":269},{"s":16,"a":26,"key":"16:26","ar":"قَدْ مَكَرَ ٱلَّذِينَ مِن قَبْلِهِمْ فَأَتَى ٱللَّهُ بُنْيَـٰنَهُم مِّنَ ٱلْقَوَاعِدِ فَخَرَّ عَلَيْهِمُ ٱلسَّقْفُ مِن فَوْقِهِمْ وَأَتَىٰهُمُ ٱلْعَذَابُ مِنْ حَيْثُ لَا يَشْعُرُونَ","en":"Those before them had already plotted, but Allāh came at [i.e., uprooted] their building from the foundations, so the roof fell upon them from above them,1 and the punishment came to them from where they did not perceive.","tr":"Qad makara allatheena min qablihimfaata Allahu bunyanahum mina alqawaAAidifakharra AAalayhimu assaqfu min fawqihim waatahumualAAathabu min haythu la yashAAuroon","juz":14,"page":269},{"s":16,"a":27,"key":"16:27","ar":"ثُمَّ يَوْمَ ٱلْقِيَـٰمَةِ يُخْزِيهِمْ وَيَقُولُ أَيْنَ شُرَكَآءِىَ ٱلَّذِينَ كُنتُمْ تُشَـٰٓقُّونَ فِيهِمْ ۚ قَالَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ إِنَّ ٱلْخِزْىَ ٱلْيَوْمَ وَٱلسُّوٓءَ عَلَى ٱلْكَـٰفِرِينَ","en":"Then on the Day of Resurrection He will disgrace them and say, \"Where are My 'partners' for whom you used to oppose [the believers]?\" Those who were given knowledge will say, \"Indeed disgrace, this Day, and evil are upon the disbelievers\" -","tr":"Thumma yawma alqiyamati yukhzeehimwayaqoolu ayna shuraka-iya allatheena kuntum tushaqqoonafeehim qala allatheena ootoo alAAilma inna alkhizyaalyawma wassoo-a AAala alkafireen","juz":14,"page":270},{"s":16,"a":28,"key":"16:28","ar":"ٱلَّذِينَ تَتَوَفَّىٰهُمُ ٱلْمَلَـٰٓئِكَةُ ظَالِمِىٓ أَنفُسِهِمْ ۖ فَأَلْقَوُا۟ ٱلسَّلَمَ مَا كُنَّا نَعْمَلُ مِن سُوٓءٍۭ ۚ بَلَىٰٓ إِنَّ ٱللَّهَ عَلِيمٌۢ بِمَا كُنتُمْ تَعْمَلُونَ","en":"The ones whom the angels take in death [while] wronging themselves,1 and [who] then offer submission, [saying], \"We were not doing any evil.\" But, yes! Indeed, Allāh is Knowing of what you used to do.","tr":"Allatheena tatawaffahumu almala-ikatuthalimee anfusihim faalqawoo assalamama kunna naAAmalu min soo-in bala inna AllahaAAaleemun bima kuntum taAAmaloon","juz":14,"page":270},{"s":16,"a":29,"key":"16:29","ar":"فَٱدْخُلُوٓا۟ أَبْوَٰبَ جَهَنَّمَ خَـٰلِدِينَ فِيهَا ۖ فَلَبِئْسَ مَثْوَى ٱلْمُتَكَبِّرِينَ","en":"So enter the gates of Hell to abide eternally therein, and how wretched is the residence of the arrogant.","tr":"Fadkhuloo abwaba jahannama khalideenafeeha falabi/sa mathwa almutakabbireen","juz":14,"page":270},{"s":16,"a":30,"key":"16:30","ar":"۞ وَقِيلَ لِلَّذِينَ ٱتَّقَوْا۟ مَاذَآ أَنزَلَ رَبُّكُمْ ۚ قَالُوا۟ خَيْرًا ۗ لِّلَّذِينَ أَحْسَنُوا۟ فِى هَـٰذِهِ ٱلدُّنْيَا حَسَنَةٌ ۚ وَلَدَارُ ٱلْـَٔاخِرَةِ خَيْرٌ ۚ وَلَنِعْمَ دَارُ ٱلْمُتَّقِينَ","en":"And it will be said to those who feared Allāh, \"What did your Lord send down?\" They will say, \"[That which is] good.\" For those who do good in this world is good; and the home of the Hereafter is better. And how excellent is the home of the righteous -","tr":"Waqeela lillatheena ittaqaw mathaanzala rabbukum qaloo khayran lillatheena ahsanoofee hathihi addunya hasanatun waladarual-akhirati khayrun walaniAAma daru almuttaqeen","juz":14,"page":270},{"s":16,"a":31,"key":"16:31","ar":"جَنَّـٰتُ عَدْنٍ يَدْخُلُونَهَا تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ۖ لَهُمْ فِيهَا مَا يَشَآءُونَ ۚ كَذَٰلِكَ يَجْزِى ٱللَّهُ ٱلْمُتَّقِينَ","en":"Gardens of perpetual residence, which they will enter, beneath which rivers flow. They will have therein whatever they wish. Thus does Allāh reward the righteous -","tr":"Jannatu AAadnin yadkhuloonahatajree min tahtiha al-anharu lahum feehama yashaoona kathalika yajzee Allahualmuttaqeen","juz":14,"page":270},{"s":16,"a":32,"key":"16:32","ar":"ٱلَّذِينَ تَتَوَفَّىٰهُمُ ٱلْمَلَـٰٓئِكَةُ طَيِّبِينَ ۙ يَقُولُونَ سَلَـٰمٌ عَلَيْكُمُ ٱدْخُلُوا۟ ٱلْجَنَّةَ بِمَا كُنتُمْ تَعْمَلُونَ","en":"The ones whom the angels take in death, [being] good and pure; [the angels] will say, \"Peace be upon you. Enter Paradise for what you used to do.\"","tr":"Allatheena tatawaffahumu almala-ikatutayyibeena yaqooloona salamun AAalaykumu odkhulooaljannata bima kuntum taAAmaloon","juz":14,"page":270},{"s":16,"a":33,"key":"16:33","ar":"هَلْ يَنظُرُونَ إِلَّآ أَن تَأْتِيَهُمُ ٱلْمَلَـٰٓئِكَةُ أَوْ يَأْتِىَ أَمْرُ رَبِّكَ ۚ كَذَٰلِكَ فَعَلَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ وَمَا ظَلَمَهُمُ ٱللَّهُ وَلَـٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ","en":"Do they [i.e., the disbelievers] await except that the angels should come to them or there comes the command of your Lord? Thus did those do before them. And Allāh wronged them not, but they had been wronging themselves.","tr":"Hal yanthuroona illa anta/tiyahumu almala-ikatu aw ya/tiya amru rabbika kathalikafaAAala allatheena min qablihim wama thalamahumuAllahu walakin kanoo anfusahum yathlimoon","juz":14,"page":270},{"s":16,"a":34,"key":"16:34","ar":"فَأَصَابَهُمْ سَيِّـَٔاتُ مَا عَمِلُوا۟ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"So they were struck by the evil consequences of what they did and were enveloped by what they used to ridicule.","tr":"Faasabahum sayyi-atu maAAamiloo wahaqa bihim ma kanoo bihiyastahzi-oon","juz":14,"page":270},{"s":16,"a":35,"key":"16:35","ar":"وَقَالَ ٱلَّذِينَ أَشْرَكُوا۟ لَوْ شَآءَ ٱللَّهُ مَا عَبَدْنَا مِن دُونِهِۦ مِن شَىْءٍ نَّحْنُ وَلَآ ءَابَآؤُنَا وَلَا حَرَّمْنَا مِن دُونِهِۦ مِن شَىْءٍ ۚ كَذَٰلِكَ فَعَلَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ فَهَلْ عَلَى ٱلرُّسُلِ إِلَّا ٱلْبَلَـٰغُ ٱلْمُبِينُ","en":"And those who associate others with Allāh say, \"If Allāh had willed, we would not have worshipped anything other than Him, neither we nor our fathers, nor would we have forbidden anything through other than Him.\" Thus did those do before them. So is there upon the messengers except [the duty of] clear notification?","tr":"Waqala allatheena ashrakoo lawshaa Allahu ma AAabadna min doonihimin shay-in nahnu wala abaonawala harramna min doonihi min shay-in kathalikafaAAala allatheena min qablihim fahal AAala arrusuliilla albalaghu almubeen","juz":14,"page":271},{"s":16,"a":36,"key":"16:36","ar":"وَلَقَدْ بَعَثْنَا فِى كُلِّ أُمَّةٍ رَّسُولًا أَنِ ٱعْبُدُوا۟ ٱللَّهَ وَٱجْتَنِبُوا۟ ٱلطَّـٰغُوتَ ۖ فَمِنْهُم مَّنْ هَدَى ٱللَّهُ وَمِنْهُم مَّنْ حَقَّتْ عَلَيْهِ ٱلضَّلَـٰلَةُ ۚ فَسِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُكَذِّبِينَ","en":"And We certainly sent into every nation a messenger, [saying], \"Worship Allāh and avoid ṭāghūt.\"1 And among them were those whom Allāh guided, and among them were those upon whom error was [deservedly] decreed. So proceed [i.e., travel] through the earth and observe how was the end of the deniers.","tr":"Walaqad baAAathna fee kulli ommatinrasoolan ani oAAbudoo Allaha wajtaniboo attaghootafaminhum man hada Allahu waminhum man haqqatAAalayhi addalalatu faseeroo fee al-ardifanthuroo kayfa kana AAaqibatualmukaththibeen","juz":14,"page":271},{"s":16,"a":37,"key":"16:37","ar":"إِن تَحْرِصْ عَلَىٰ هُدَىٰهُمْ فَإِنَّ ٱللَّهَ لَا يَهْدِى مَن يُضِلُّ ۖ وَمَا لَهُم مِّن نَّـٰصِرِينَ","en":"[Even] if you should strive for their guidance, [O Muḥammad], indeed, Allāh does not guide those He sends astray,1 and they will have no helpers.","tr":"In tahris AAala hudahumfa-inna Allaha la yahdee man yudillu wamalahum min nasireen","juz":14,"page":271},{"s":16,"a":38,"key":"16:38","ar":"وَأَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَـٰنِهِمْ ۙ لَا يَبْعَثُ ٱللَّهُ مَن يَمُوتُ ۚ بَلَىٰ وَعْدًا عَلَيْهِ حَقًّا وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"And they swear by Allāh their strongest oaths [that] Allāh will not resurrect one who dies. But yes - [it is] a true promise [binding] upon Him, but most of the people do not know.","tr":"Waaqsamoo billahi jahda aymanihimla yabAAathu Allahu man yamootu bala waAAdanAAalayhi haqqan walakinna akthara annasila yaAAlamoon","juz":14,"page":271},{"s":16,"a":39,"key":"16:39","ar":"لِيُبَيِّنَ لَهُمُ ٱلَّذِى يَخْتَلِفُونَ فِيهِ وَلِيَعْلَمَ ٱلَّذِينَ كَفَرُوٓا۟ أَنَّهُمْ كَانُوا۟ كَـٰذِبِينَ","en":"[It is] so He will make clear to them [the truth of] that wherein they differ and so those who have disbelieved may know that they were liars.","tr":"Liyubayyina lahumu allatheeyakhtalifoona feehi waliyaAAlama allatheena kafarooannahum kanoo kathibeen","juz":14,"page":271},{"s":16,"a":40,"key":"16:40","ar":"إِنَّمَا قَوْلُنَا لِشَىْءٍ إِذَآ أَرَدْنَـٰهُ أَن نَّقُولَ لَهُۥ كُن فَيَكُونُ","en":"Indeed, Our word to a thing when We intend it is but that We say to it, \"Be,\" and it is.","tr":"Innama qawluna lishay-inithaaradnahu an naqoola lahu kun fayakoon","juz":14,"page":271},{"s":16,"a":41,"key":"16:41","ar":"وَٱلَّذِينَ هَاجَرُوا۟ فِى ٱللَّهِ مِنۢ بَعْدِ مَا ظُلِمُوا۟ لَنُبَوِّئَنَّهُمْ فِى ٱلدُّنْيَا حَسَنَةً ۖ وَلَأَجْرُ ٱلْـَٔاخِرَةِ أَكْبَرُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ","en":"And those who emigrated for [the cause of] Allāh after they had been wronged - We will surely settle them in this world in a good place; but the reward of the Hereafter is greater, if only they could know.","tr":"Wallatheena hajaroofee Allahi min baAAdi ma thulimoolanubawwi-annahum fee addunya hasanatanwalaajru al-akhirati akbaru law kanoo yaAAlamoon","juz":14,"page":271},{"s":16,"a":42,"key":"16:42","ar":"ٱلَّذِينَ صَبَرُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ","en":"[They are] those who endured patiently and upon their Lord relied.","tr":"Allatheena sabaroo waAAalarabbihim yatawakkaloon","juz":14,"page":271},{"s":16,"a":43,"key":"16:43","ar":"وَمَآ أَرْسَلْنَا مِن قَبْلِكَ إِلَّا رِجَالًا نُّوحِىٓ إِلَيْهِمْ ۚ فَسْـَٔلُوٓا۟ أَهْلَ ٱلذِّكْرِ إِن كُنتُمْ لَا تَعْلَمُونَ","en":"And We sent not before you except men to whom We revealed [Our message]. So ask the people of the message [i.e., former scriptures] if you do not know.","tr":"Wama arsalna min qablika illarijalan noohee ilayhim fas-aloo ahla aththikriin kuntum la taAAlamoon","juz":14,"page":272},{"s":16,"a":44,"key":"16:44","ar":"بِٱلْبَيِّنَـٰتِ وَٱلزُّبُرِ ۗ وَأَنزَلْنَآ إِلَيْكَ ٱلذِّكْرَ لِتُبَيِّنَ لِلنَّاسِ مَا نُزِّلَ إِلَيْهِمْ وَلَعَلَّهُمْ يَتَفَكَّرُونَ","en":"[We sent them] with clear proofs and written ordinances. And We revealed to you the message [i.e., the Qur’ān] that you may make clear to the people what was sent down to them and that they might give thought.","tr":"Bilbayyinati wazzuburiwaanzalna ilayka aththikra litubayyina linnasima nuzzila ilayhim walaAAallahum yatafakkaroon","juz":14,"page":272},{"s":16,"a":45,"key":"16:45","ar":"أَفَأَمِنَ ٱلَّذِينَ مَكَرُوا۟ ٱلسَّيِّـَٔاتِ أَن يَخْسِفَ ٱللَّهُ بِهِمُ ٱلْأَرْضَ أَوْ يَأْتِيَهُمُ ٱلْعَذَابُ مِنْ حَيْثُ لَا يَشْعُرُونَ","en":"Then, do those who have planned evil deeds feel secure that Allāh will not cause the earth to swallow them or that the punishment will not come upon them from where they do not perceive?","tr":"Afaamina allatheena makaroo assayyi-atian yakhsifa Allahu bihimu al-arda aw ya/tiyahumualAAathabu min haythu la yashAAuroon","juz":14,"page":272},{"s":16,"a":46,"key":"16:46","ar":"أَوْ يَأْخُذَهُمْ فِى تَقَلُّبِهِمْ فَمَا هُم بِمُعْجِزِينَ","en":"Or that He would not seize them during their [usual] activity, and they could not cause failure [i.e., escape from Him]?","tr":"Aw ya/khuthahum fee taqallubihim famahum bimuAAjizeen","juz":14,"page":272},{"s":16,"a":47,"key":"16:47","ar":"أَوْ يَأْخُذَهُمْ عَلَىٰ تَخَوُّفٍ فَإِنَّ رَبَّكُمْ لَرَءُوفٌ رَّحِيمٌ","en":"Or that He would not seize them gradually [in a state of dread]?1 But indeed, your Lord is Kind and Merciful.2","tr":"Aw ya/khuthahum AAalatakhawwufin fa-inna rabbakum laraoofun raheem","juz":14,"page":272},{"s":16,"a":48,"key":"16:48","ar":"أَوَلَمْ يَرَوْا۟ إِلَىٰ مَا خَلَقَ ٱللَّهُ مِن شَىْءٍ يَتَفَيَّؤُا۟ ظِلَـٰلُهُۥ عَنِ ٱلْيَمِينِ وَٱلشَّمَآئِلِ سُجَّدًا لِّلَّهِ وَهُمْ دَٰخِرُونَ","en":"Have they not considered what things Allāh has created? Their shadows incline to the right and to the left, prostrating to Allāh, while they [i.e., those creations] are humble.","tr":"Awa lam yaraw ila ma khalaqaAllahu min shay-in yatafayyao thilaluhuAAani alyameeni washshama-ili sujjadan lillahiwahum dakhiroon","juz":14,"page":272},{"s":16,"a":49,"key":"16:49","ar":"وَلِلَّهِ يَسْجُدُ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ مِن دَآبَّةٍ وَٱلْمَلَـٰٓئِكَةُ وَهُمْ لَا يَسْتَكْبِرُونَ","en":"And to Allāh prostrates whatever is in the heavens and whatever is on the earth of creatures, and the angels [as well], and they are not arrogant.","tr":"Walillahi yasjudu ma fee assamawatiwama fee al-ardi min dabbatin walmala-ikatuwahum la yastakbiroon","juz":14,"page":272},{"s":16,"a":50,"key":"16:50","ar":"يَخَافُونَ رَبَّهُم مِّن فَوْقِهِمْ وَيَفْعَلُونَ مَا يُؤْمَرُونَ ۩","en":"They fear their Lord above them, and they do what they are commanded.","tr":"Yakhafoona rabbahum min fawqihimwayafAAaloona ma yu/maroon","juz":14,"page":272},{"s":16,"a":51,"key":"16:51","ar":"۞ وَقَالَ ٱللَّهُ لَا تَتَّخِذُوٓا۟ إِلَـٰهَيْنِ ٱثْنَيْنِ ۖ إِنَّمَا هُوَ إِلَـٰهٌ وَٰحِدٌ ۖ فَإِيَّـٰىَ فَٱرْهَبُونِ","en":"And Allāh has said, \"Do not take for yourselves two1 deities. He [i.e., Allāh] is but one God, so fear only Me.\"","tr":"Waqala Allahu latattakhithoo ilahayni ithnayni innama huwailahun wahidun fa-iyyaya farhaboon","juz":14,"page":272},{"s":16,"a":52,"key":"16:52","ar":"وَلَهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَلَهُ ٱلدِّينُ وَاصِبًا ۚ أَفَغَيْرَ ٱللَّهِ تَتَّقُونَ","en":"And to Him belongs whatever is in the heavens and the earth, and to Him is [due] worship constantly. Then is it other than Allāh that you fear?","tr":"Walahu ma fee assamawatiwal-ardi walahu addeenu wasibanafaghayra Allahi tattaqoon","juz":14,"page":272},{"s":16,"a":53,"key":"16:53","ar":"وَمَا بِكُم مِّن نِّعْمَةٍ فَمِنَ ٱللَّهِ ۖ ثُمَّ إِذَا مَسَّكُمُ ٱلضُّرُّ فَإِلَيْهِ تَجْـَٔرُونَ","en":"And whatever you have of favor - it is from Allāh. Then when adversity touches you, to Him you cry for help.","tr":"Wama bikum min niAAmatin famina Allahithumma itha massakumu addurru fa-ilayhitaj-aroon","juz":14,"page":272},{"s":16,"a":54,"key":"16:54","ar":"ثُمَّ إِذَا كَشَفَ ٱلضُّرَّ عَنكُمْ إِذَا فَرِيقٌ مِّنكُم بِرَبِّهِمْ يُشْرِكُونَ","en":"Then when He removes the adversity from you, at once a party of you associates others with their Lord","tr":"Thumma itha kashafa addurraAAankum itha fareequn minkum birabbihim yushrikoon","juz":14,"page":272},{"s":16,"a":55,"key":"16:55","ar":"لِيَكْفُرُوا۟ بِمَآ ءَاتَيْنَـٰهُمْ ۚ فَتَمَتَّعُوا۟ ۖ فَسَوْفَ تَعْلَمُونَ","en":"So they will deny what We have given them. Then enjoy yourselves, for you are going to know.","tr":"Liyakfuroo bima ataynahumfatamattaAAoo fasawfa taAAlamoon","juz":14,"page":273},{"s":16,"a":56,"key":"16:56","ar":"وَيَجْعَلُونَ لِمَا لَا يَعْلَمُونَ نَصِيبًا مِّمَّا رَزَقْنَـٰهُمْ ۗ تَٱللَّهِ لَتُسْـَٔلُنَّ عَمَّا كُنتُمْ تَفْتَرُونَ","en":"And they assign to what they do not know1 [i.e., false deities] a portion of that which We have provided them. By Allāh, you will surely be questioned about what you used to invent.","tr":"WayajAAaloona lima layaAAlamoona naseeban mimma razaqnahum tallahilatus-alunna AAamma kuntum taftaroon","juz":14,"page":273},{"s":16,"a":57,"key":"16:57","ar":"وَيَجْعَلُونَ لِلَّهِ ٱلْبَنَـٰتِ سُبْحَـٰنَهُۥ ۙ وَلَهُم مَّا يَشْتَهُونَ","en":"And they attribute to Allāh daughters1 - exalted is He - and for them is what they desire [i.e., sons].","tr":"WayajAAaloona lillahi albanatisubhanahu walahum ma yashtahoon","juz":14,"page":273},{"s":16,"a":58,"key":"16:58","ar":"وَإِذَا بُشِّرَ أَحَدُهُم بِٱلْأُنثَىٰ ظَلَّ وَجْهُهُۥ مُسْوَدًّا وَهُوَ كَظِيمٌ","en":"And when one of them is informed of [the birth of] a female, his face becomes dark, and he suppresses grief.","tr":"Wa-itha bushshira ahaduhum bilonthathalla wajhuhu muswaddan wahuwa katheem","juz":14,"page":273},{"s":16,"a":59,"key":"16:59","ar":"يَتَوَٰرَىٰ مِنَ ٱلْقَوْمِ مِن سُوٓءِ مَا بُشِّرَ بِهِۦٓ ۚ أَيُمْسِكُهُۥ عَلَىٰ هُونٍ أَمْ يَدُسُّهُۥ فِى ٱلتُّرَابِ ۗ أَلَا سَآءَ مَا يَحْكُمُونَ","en":"He hides himself from the people because of the ill of which he has been informed. Should he keep it in humiliation or bury it in the ground? Unquestionably, evil is what they decide.","tr":"Yatawara mina alqawmi minsoo-i ma bushshira bihi ayumsikuhu AAala hoonin amyadussuhu fee atturabi ala saa mayahkumoon","juz":14,"page":273},{"s":16,"a":60,"key":"16:60","ar":"لِلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ مَثَلُ ٱلسَّوْءِ ۖ وَلِلَّهِ ٱلْمَثَلُ ٱلْأَعْلَىٰ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"For those who do not believe in the Hereafter is the description [i.e., an attribute] of evil;1 and for Allāh is the highest attribute. And He is Exalted in Might, the Wise.","tr":"Lillatheena la yu/minoona bil-akhiratimathalu assaw-i walillahi almathalu al-aAAlawahuwa alAAazeezu alhakeem","juz":14,"page":273},{"s":16,"a":61,"key":"16:61","ar":"وَلَوْ يُؤَاخِذُ ٱللَّهُ ٱلنَّاسَ بِظُلْمِهِم مَّا تَرَكَ عَلَيْهَا مِن دَآبَّةٍ وَلَـٰكِن يُؤَخِّرُهُمْ إِلَىٰٓ أَجَلٍ مُّسَمًّى ۖ فَإِذَا جَآءَ أَجَلُهُمْ لَا يَسْتَـْٔخِرُونَ سَاعَةً ۖ وَلَا يَسْتَقْدِمُونَ","en":"And if Allāh were to impose blame on the people for their wrongdoing, He would not have left upon it [i.e., the earth] any creature, but He defers them for a specified term. And when their term has come, they will not remain behind an hour, nor will they precede [it].","tr":"Walaw yu-akhithu Allahuannasa bithulmihim ma tarakaAAalayha min dabbatin walakin yu-akhkhiruhumila ajalin musamman fa-itha jaa ajaluhum layasta/khiroona saAAatan wala yastaqdimoon","juz":14,"page":273},{"s":16,"a":62,"key":"16:62","ar":"وَيَجْعَلُونَ لِلَّهِ مَا يَكْرَهُونَ وَتَصِفُ أَلْسِنَتُهُمُ ٱلْكَذِبَ أَنَّ لَهُمُ ٱلْحُسْنَىٰ ۖ لَا جَرَمَ أَنَّ لَهُمُ ٱلنَّارَ وَأَنَّهُم مُّفْرَطُونَ","en":"And they attribute to Allāh that which they dislike [i.e., daughters], and their tongues assert the lie that they will have the best [from Him]. Assuredly, they will have the Fire, and they will be [therein] neglected.1","tr":"WayajAAaloona lillahi mayakrahoona watasifu alsinatuhumu alkathiba annalahumu alhusna la jarama anna lahumu annarawaannahum mufratoon","juz":14,"page":273},{"s":16,"a":63,"key":"16:63","ar":"تَٱللَّهِ لَقَدْ أَرْسَلْنَآ إِلَىٰٓ أُمَمٍ مِّن قَبْلِكَ فَزَيَّنَ لَهُمُ ٱلشَّيْطَـٰنُ أَعْمَـٰلَهُمْ فَهُوَ وَلِيُّهُمُ ٱلْيَوْمَ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"By Allāh, We did certainly send [messengers] to nations before you, but Satan made their deeds attractive to them. And he is their [i.e., the disbelievers] ally today [as well], and they will have a painful punishment.","tr":"Tallahi laqad arsalnaila omamin min qablika fazayyana lahumu ashshaytanuaAAmalahum fahuwa waliyyuhumu alyawma walahum AAathabunaleem","juz":14,"page":273},{"s":16,"a":64,"key":"16:64","ar":"وَمَآ أَنزَلْنَا عَلَيْكَ ٱلْكِتَـٰبَ إِلَّا لِتُبَيِّنَ لَهُمُ ٱلَّذِى ٱخْتَلَفُوا۟ فِيهِ ۙ وَهُدًى وَرَحْمَةً لِّقَوْمٍ يُؤْمِنُونَ","en":"And We have not revealed to you the Book, [O Muḥammad], except for you to make clear to them that wherein they have differed and as guidance and mercy for a people who believe.","tr":"Wama anzalna AAalayka alkitabailla litubayyina lahumu allathee ikhtalafoo feehiwahudan warahmatan liqawmin yu/minoon","juz":14,"page":273},{"s":16,"a":65,"key":"16:65","ar":"وَٱللَّهُ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً فَأَحْيَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَآ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّقَوْمٍ يَسْمَعُونَ","en":"And Allāh has sent down rain from the sky and given life thereby to the earth after its lifelessness. Indeed in that is a sign for a people who listen.","tr":"Wallahu anzala mina assama-imaan faahya bihi al-arda baAAdamawtiha inna fee thalika laayatan liqawminyasmaAAoon","juz":14,"page":274},{"s":16,"a":66,"key":"16:66","ar":"وَإِنَّ لَكُمْ فِى ٱلْأَنْعَـٰمِ لَعِبْرَةً ۖ نُّسْقِيكُم مِّمَّا فِى بُطُونِهِۦ مِنۢ بَيْنِ فَرْثٍ وَدَمٍ لَّبَنًا خَالِصًا سَآئِغًا لِّلشَّـٰرِبِينَ","en":"And indeed, for you in grazing livestock is a lesson. We give you drink from what is in their bellies - between excretion and blood - pure milk, palatable to drinkers.","tr":"Wa-inna lakum fee al-anAAamilaAAibratan nusqeekum mimma fee butoonihi min baynifarthin wadamin labanan khalisan sa-ighan lishsharibeen","juz":14,"page":274},{"s":16,"a":67,"key":"16:67","ar":"وَمِن ثَمَرَٰتِ ٱلنَّخِيلِ وَٱلْأَعْنَـٰبِ تَتَّخِذُونَ مِنْهُ سَكَرًا وَرِزْقًا حَسَنًا ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّقَوْمٍ يَعْقِلُونَ","en":"And from the fruits of the palm trees and grapevines you take intoxicant and good provision.1 Indeed in that is a sign for a people who reason.","tr":"Wamin thamarati annakheeli wal-aAAnabitattakhithoona minhu sakaran warizqan hasanan innafee thalika laayatan liqawmin yaAAqiloon","juz":14,"page":274},{"s":16,"a":68,"key":"16:68","ar":"وَأَوْحَىٰ رَبُّكَ إِلَى ٱلنَّحْلِ أَنِ ٱتَّخِذِى مِنَ ٱلْجِبَالِ بُيُوتًا وَمِنَ ٱلشَّجَرِ وَمِمَّا يَعْرِشُونَ","en":"And your Lord inspired to the bee, \"Take for yourself among the mountains, houses [i.e., hives], and among the trees and [in] that which they construct.","tr":"Waawha rabbuka ila annahliani ittakhithee mina aljibali buyootan wamina ashshajariwamimma yaAArishoon","juz":14,"page":274},{"s":16,"a":69,"key":"16:69","ar":"ثُمَّ كُلِى مِن كُلِّ ٱلثَّمَرَٰتِ فَٱسْلُكِى سُبُلَ رَبِّكِ ذُلُلًا ۚ يَخْرُجُ مِنۢ بُطُونِهَا شَرَابٌ مُّخْتَلِفٌ أَلْوَٰنُهُۥ فِيهِ شِفَآءٌ لِّلنَّاسِ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّقَوْمٍ يَتَفَكَّرُونَ","en":"Then eat from all the fruits1 and follow the ways of your Lord laid down [for you].\" There emerges from their bellies a drink, varying in colors, in which there is healing for people. Indeed in that is a sign for a people who give thought.","tr":"Thumma kulee min kulli aththamaratifaslukee subula rabbiki thululan yakhruju min butoonihasharabun mukhtalifun alwanuhu feehi shifaonlinnasi inna fee thalika laayatanliqawmin yatafakkaroon","juz":14,"page":274},{"s":16,"a":70,"key":"16:70","ar":"وَٱللَّهُ خَلَقَكُمْ ثُمَّ يَتَوَفَّىٰكُمْ ۚ وَمِنكُم مَّن يُرَدُّ إِلَىٰٓ أَرْذَلِ ٱلْعُمُرِ لِكَىْ لَا يَعْلَمَ بَعْدَ عِلْمٍ شَيْـًٔا ۚ إِنَّ ٱللَّهَ عَلِيمٌ قَدِيرٌ","en":"And Allāh created you; then He will take you in death. And among you is he who is reversed to the most decrepit [old] age so that he will not know, after [having had] knowledge, a thing. Indeed, Allāh is Knowing and Competent.","tr":"Wallahu khalaqakum thummayatawaffakum waminkum man yuraddu ila arthalialAAumuri likay la yaAAlama baAAda AAilmin shay-an innaAllaha AAaleemun qadeer","juz":14,"page":274},{"s":16,"a":71,"key":"16:71","ar":"وَٱللَّهُ فَضَّلَ بَعْضَكُمْ عَلَىٰ بَعْضٍ فِى ٱلرِّزْقِ ۚ فَمَا ٱلَّذِينَ فُضِّلُوا۟ بِرَآدِّى رِزْقِهِمْ عَلَىٰ مَا مَلَكَتْ أَيْمَـٰنُهُمْ فَهُمْ فِيهِ سَوَآءٌ ۚ أَفَبِنِعْمَةِ ٱللَّهِ يَجْحَدُونَ","en":"And Allāh has favored some of you over others in provision. But those who were favored [i.e., given more] would not hand over their provision to those whom their right hands possess [i.e., slaves] so they would be equal to them therein.1 Then is it the favor of Allāh they reject?","tr":"Wallahu faddala baAAdakumAAala baAAdin fee arrizqi fama allatheenafuddiloo biraddee rizqihim AAala mamalakat aymanuhum fahum feehi sawaon afabiniAAmatiAllahi yajhadoon","juz":14,"page":274},{"s":16,"a":72,"key":"16:72","ar":"وَٱللَّهُ جَعَلَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَٰجًا وَجَعَلَ لَكُم مِّنْ أَزْوَٰجِكُم بَنِينَ وَحَفَدَةً وَرَزَقَكُم مِّنَ ٱلطَّيِّبَـٰتِ ۚ أَفَبِٱلْبَـٰطِلِ يُؤْمِنُونَ وَبِنِعْمَتِ ٱللَّهِ هُمْ يَكْفُرُونَ","en":"And Allāh has made for you from yourselves mates and has made for you from your mates sons and grandchildren and has provided for you from the good things. Then in falsehood do they believe and in the favor of Allāh they disbelieve?","tr":"Wallahu jaAAala lakum minanfusikum azwajan wajaAAala lakum min azwajikumbaneena wahafadatan warazaqakum mina attayyibatiafabilbatili yu/minoona wabiniAAmati Allahihum yakfuroon","juz":14,"page":274},{"s":16,"a":73,"key":"16:73","ar":"وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَمْلِكُ لَهُمْ رِزْقًا مِّنَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ شَيْـًٔا وَلَا يَسْتَطِيعُونَ","en":"And they worship besides Allāh that which does not possess for them [the power of] provision from the heavens and the earth at all, and [in fact], they are unable.","tr":"WayaAAbudoona min dooni Allahi mala yamliku lahum rizqan mina assamawatiwal-ardi shay-an wala yastateeAAoon","juz":14,"page":275},{"s":16,"a":74,"key":"16:74","ar":"فَلَا تَضْرِبُوا۟ لِلَّهِ ٱلْأَمْثَالَ ۚ إِنَّ ٱللَّهَ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ","en":"So do not assert similarities to Allāh.1 Indeed, Allāh knows and you do not know.","tr":"Fala tadriboo lillahial-amthala inna Allaha yaAAlamu waantum lataAAlamoon","juz":14,"page":275},{"s":16,"a":75,"key":"16:75","ar":"۞ ضَرَبَ ٱللَّهُ مَثَلًا عَبْدًا مَّمْلُوكًا لَّا يَقْدِرُ عَلَىٰ شَىْءٍ وَمَن رَّزَقْنَـٰهُ مِنَّا رِزْقًا حَسَنًا فَهُوَ يُنفِقُ مِنْهُ سِرًّا وَجَهْرًا ۖ هَلْ يَسْتَوُۥنَ ۚ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ","en":"Allāh presents an example: a slave [who is] owned and unable to do a thing and he to whom We have provided from Us good provision, so he spends from it secretly and publicly. Can they be equal? Praise to Allāh! But most of them do not know.","tr":"Daraba Allahu mathalan AAabdanmamlookan la yaqdiru AAala shay-in waman razaqnahuminna rizqan hasanan fahuwa yunfiqu minhu sirranwajahran hal yastawoona alhamdu lillahi balaktharuhum la yaAAlamoon","juz":14,"page":275},{"s":16,"a":76,"key":"16:76","ar":"وَضَرَبَ ٱللَّهُ مَثَلًا رَّجُلَيْنِ أَحَدُهُمَآ أَبْكَمُ لَا يَقْدِرُ عَلَىٰ شَىْءٍ وَهُوَ كَلٌّ عَلَىٰ مَوْلَىٰهُ أَيْنَمَا يُوَجِّههُّ لَا يَأْتِ بِخَيْرٍ ۖ هَلْ يَسْتَوِى هُوَ وَمَن يَأْمُرُ بِٱلْعَدْلِ ۙ وَهُوَ عَلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"And Allāh presents an example of two men, one of them dumb and unable to do a thing, while he is a burden to his guardian. Wherever he directs him, he brings no good. Is he equal to one who commands justice, while he is on a straight path?","tr":"Wadaraba Allahu mathalanrajulayni ahaduhuma abkamu la yaqdiru AAalashay-in wahuwa kallun AAala mawlahu aynamayuwajjihhu la ya/ti bikhayrin hal yastawee huwa wamanya/muru bilAAadli wahuwa AAala siratinmustaqeem","juz":14,"page":275},{"s":16,"a":77,"key":"16:77","ar":"وَلِلَّهِ غَيْبُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَمَآ أَمْرُ ٱلسَّاعَةِ إِلَّا كَلَمْحِ ٱلْبَصَرِ أَوْ هُوَ أَقْرَبُ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"And to Allāh belongs the unseen [aspects] of the heavens and the earth. And the command for the Hour is not but as a glance of the eye or even nearer. Indeed, Allāh is over all things competent.","tr":"Walillahi ghaybu assamawatiwal-ardi wama amru assaAAatiilla kalamhi albasari aw huwa aqrabu innaAllaha AAala kulli shay-in qadeer","juz":14,"page":275},{"s":16,"a":78,"key":"16:78","ar":"وَٱللَّهُ أَخْرَجَكُم مِّنۢ بُطُونِ أُمَّهَـٰتِكُمْ لَا تَعْلَمُونَ شَيْـًٔا وَجَعَلَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَـٰرَ وَٱلْأَفْـِٔدَةَ ۙ لَعَلَّكُمْ تَشْكُرُونَ","en":"And Allāh has extracted you from the wombs of your mothers not knowing a thing, and He made for you hearing and vision and hearts [i.e., intellect] that perhaps you would be grateful.","tr":"Wallahu akhrajakum min butooniommahatikum la taAAlamoona shay-an wajaAAala lakumuassamAAa wal-absara wal-af-idatalaAAallakum tashkuroon","juz":14,"page":275},{"s":16,"a":79,"key":"16:79","ar":"أَلَمْ يَرَوْا۟ إِلَى ٱلطَّيْرِ مُسَخَّرَٰتٍ فِى جَوِّ ٱلسَّمَآءِ مَا يُمْسِكُهُنَّ إِلَّا ٱللَّهُ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يُؤْمِنُونَ","en":"Do they not see the birds controlled in the atmosphere of the sky? None holds them up except Allāh. Indeed in that are signs for a people who believe.","tr":"Alam yaraw ila attayrimusakhkharatin fee jawwi assama-i mayumsikuhunna illa Allahu inna fee thalika laayatinliqawmin yu/minoon","juz":14,"page":275},{"s":16,"a":80,"key":"16:80","ar":"وَٱللَّهُ جَعَلَ لَكُم مِّنۢ بُيُوتِكُمْ سَكَنًا وَجَعَلَ لَكُم مِّن جُلُودِ ٱلْأَنْعَـٰمِ بُيُوتًا تَسْتَخِفُّونَهَا يَوْمَ ظَعْنِكُمْ وَيَوْمَ إِقَامَتِكُمْ ۙ وَمِنْ أَصْوَافِهَا وَأَوْبَارِهَا وَأَشْعَارِهَآ أَثَـٰثًا وَمَتَـٰعًا إِلَىٰ حِينٍ","en":"And Allāh has made for you from your homes a place of rest and made for you from the hides of the animals tents which you find light on your day of travel and your day of encampment; and from their wool, fur and hair is furnishing and enjoyment [i.e., provision] for a time.","tr":"Wallahu jaAAala lakum minbuyootikum sakanan wajaAAala lakum min juloodi al-anAAamibuyootan tastakhiffoonaha yawma thaAAnikumwayawma iqamatikum wamin aswafihawaawbariha waashAAariha athathanwamataAAan ila heen","juz":14,"page":276},{"s":16,"a":81,"key":"16:81","ar":"وَٱللَّهُ جَعَلَ لَكُم مِّمَّا خَلَقَ ظِلَـٰلًا وَجَعَلَ لَكُم مِّنَ ٱلْجِبَالِ أَكْنَـٰنًا وَجَعَلَ لَكُمْ سَرَٰبِيلَ تَقِيكُمُ ٱلْحَرَّ وَسَرَٰبِيلَ تَقِيكُم بَأْسَكُمْ ۚ كَذَٰلِكَ يُتِمُّ نِعْمَتَهُۥ عَلَيْكُمْ لَعَلَّكُمْ تُسْلِمُونَ","en":"And Allāh has made for you, from that which He has created, shadows [i.e., shade] and has made for you from the mountains, shelters and has made for you garments which protect you from the heat and garments [i.e., coats of mail] which protect you from your [enemy in] battle. Thus does He complete His favor upon you that you might submit [to Him].","tr":"Wallahu jaAAala lakum mimmakhalaqa thilalan wajaAAala lakum mina aljibaliaknanan wajaAAala lakum sarabeela taqeekumu alharrawasarabeela taqeekum ba/sakum kathalika yutimmuniAAmatahu AAalaykum laAAallakum tuslimoon","juz":14,"page":276},{"s":16,"a":82,"key":"16:82","ar":"فَإِن تَوَلَّوْا۟ فَإِنَّمَا عَلَيْكَ ٱلْبَلَـٰغُ ٱلْمُبِينُ","en":"But if they turn away, [O Muḥammad] - then only upon you is [responsibility for] clear notification.","tr":"Fa-in tawallaw fa-innama AAalaykaalbalaghu almubeen","juz":14,"page":276},{"s":16,"a":83,"key":"16:83","ar":"يَعْرِفُونَ نِعْمَتَ ٱللَّهِ ثُمَّ يُنكِرُونَهَا وَأَكْثَرُهُمُ ٱلْكَـٰفِرُونَ","en":"They recognize the favor of Allāh; then they deny it. And most of them are disbelievers.","tr":"YaAArifoona niAAmata Allahi thummayunkiroonaha waaktharuhumu alkafiroon","juz":14,"page":276},{"s":16,"a":84,"key":"16:84","ar":"وَيَوْمَ نَبْعَثُ مِن كُلِّ أُمَّةٍ شَهِيدًا ثُمَّ لَا يُؤْذَنُ لِلَّذِينَ كَفَرُوا۟ وَلَا هُمْ يُسْتَعْتَبُونَ","en":"And [mention] the Day when We will resurrect from every nation a witness [i.e., their prophet]. Then it will not be permitted to the disbelievers [to apologize or make excuses], nor will they be asked to appease [Allāh].","tr":"Wayawma nabAAathu min kulli ommatinshaheedan thumma la yu/thanu lillatheenakafaroo wala hum yustaAAtaboon","juz":14,"page":276},{"s":16,"a":85,"key":"16:85","ar":"وَإِذَا رَءَا ٱلَّذِينَ ظَلَمُوا۟ ٱلْعَذَابَ فَلَا يُخَفَّفُ عَنْهُمْ وَلَا هُمْ يُنظَرُونَ","en":"And when those who wronged see the punishment, it will not be lightened for them, nor will they be reprieved.","tr":"Wa-itha raa allatheena thalamooalAAathaba fala yukhaffafu AAanhum wala humyuntharoon","juz":14,"page":276},{"s":16,"a":86,"key":"16:86","ar":"وَإِذَا رَءَا ٱلَّذِينَ أَشْرَكُوا۟ شُرَكَآءَهُمْ قَالُوا۟ رَبَّنَا هَـٰٓؤُلَآءِ شُرَكَآؤُنَا ٱلَّذِينَ كُنَّا نَدْعُوا۟ مِن دُونِكَ ۖ فَأَلْقَوْا۟ إِلَيْهِمُ ٱلْقَوْلَ إِنَّكُمْ لَكَـٰذِبُونَ","en":"And when those who associated others with Allāh see their \"partners,\" they will say, \"Our Lord, these are our partners [to You] whom we used to invoke [in worship] besides You.\" But they will throw at them the statement, \"Indeed, you are liars.\"","tr":"Wa-itha raa allatheenaashrakoo shurakaahum qaloo rabbana haola-ishurakaona allatheena kunna nadAAoomin doonika faalqaw ilayhimu alqawla innakum lakathiboon","juz":14,"page":276},{"s":16,"a":87,"key":"16:87","ar":"وَأَلْقَوْا۟ إِلَى ٱللَّهِ يَوْمَئِذٍ ٱلسَّلَمَ ۖ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ","en":"And they will impart to Allāh that Day [their] submission, and lost from them is what they used to invent.","tr":"Waalqaw ila Allahi yawma-ithinassalama wadalla AAanhum ma kanooyaftaroon","juz":14,"page":276},{"s":16,"a":88,"key":"16:88","ar":"ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ زِدْنَـٰهُمْ عَذَابًا فَوْقَ ٱلْعَذَابِ بِمَا كَانُوا۟ يُفْسِدُونَ","en":"Those who disbelieved and averted [others] from the way of Allāh - We will increase them in punishment over [their] punishment for what corruption they were causing.","tr":"Allatheena kafaroo wasaddooAAan sabeeli Allahi zidnahum AAathaban fawqaalAAathabi bima kanoo yufsidoon","juz":14,"page":277},{"s":16,"a":89,"key":"16:89","ar":"وَيَوْمَ نَبْعَثُ فِى كُلِّ أُمَّةٍ شَهِيدًا عَلَيْهِم مِّنْ أَنفُسِهِمْ ۖ وَجِئْنَا بِكَ شَهِيدًا عَلَىٰ هَـٰٓؤُلَآءِ ۚ وَنَزَّلْنَا عَلَيْكَ ٱلْكِتَـٰبَ تِبْيَـٰنًا لِّكُلِّ شَىْءٍ وَهُدًى وَرَحْمَةً وَبُشْرَىٰ لِلْمُسْلِمِينَ","en":"And [mention] the Day when We will resurrect among every nation a witness over them from themselves [i.e., their prophet]. And We will bring you, [O Muḥammad], as a witness over these [i.e., your nation]. And We have sent down to you the Book as clarification for all things and as guidance and mercy and good tidings for the Muslims.1","tr":"Wayawma nabAAathu fee kulli ommatinshaheedan AAalayhim min anfusihim waji/na bika shaheedanAAala haola-i wanazzalna AAalaykaalkitaba tibyanan likulli shay-in wahudan warahmatanwabushra lilmuslimeen","juz":14,"page":277},{"s":16,"a":90,"key":"16:90","ar":"۞ إِنَّ ٱللَّهَ يَأْمُرُ بِٱلْعَدْلِ وَٱلْإِحْسَـٰنِ وَإِيتَآئِ ذِى ٱلْقُرْبَىٰ وَيَنْهَىٰ عَنِ ٱلْفَحْشَآءِ وَٱلْمُنكَرِ وَٱلْبَغْىِ ۚ يَعِظُكُمْ لَعَلَّكُمْ تَذَكَّرُونَ","en":"Indeed, Allāh orders justice and good conduct and giving [help] to relatives and forbids immorality and bad conduct and oppression. He admonishes you that perhaps you will be reminded.","tr":"Inna Allaha ya/muru bilAAadliwal-ihsani wa-eeta-i theealqurba wayanha AAani alfahsha-i walmunkariwalbaghyi yaAAithukum laAAallakum tathakkaroon","juz":14,"page":277},{"s":16,"a":91,"key":"16:91","ar":"وَأَوْفُوا۟ بِعَهْدِ ٱللَّهِ إِذَا عَـٰهَدتُّمْ وَلَا تَنقُضُوا۟ ٱلْأَيْمَـٰنَ بَعْدَ تَوْكِيدِهَا وَقَدْ جَعَلْتُمُ ٱللَّهَ عَلَيْكُمْ كَفِيلًا ۚ إِنَّ ٱللَّهَ يَعْلَمُ مَا تَفْعَلُونَ","en":"And fulfill the covenant of Allāh when you have taken it, [O believers], and do not break oaths after their confirmation while you have made Allāh, over you, a security [i.e., witness]. Indeed, Allāh knows what you do.","tr":"Waawfoo biAAahdi Allahi ithaAAahadtum wala tanqudoo al-aymanabaAAda tawkeediha waqad jaAAaltumu Allaha AAalaykumkafeelan inna Allaha yaAAlamu ma tafAAaloon","juz":14,"page":277},{"s":16,"a":92,"key":"16:92","ar":"وَلَا تَكُونُوا۟ كَٱلَّتِى نَقَضَتْ غَزْلَهَا مِنۢ بَعْدِ قُوَّةٍ أَنكَـٰثًا تَتَّخِذُونَ أَيْمَـٰنَكُمْ دَخَلًۢا بَيْنَكُمْ أَن تَكُونَ أُمَّةٌ هِىَ أَرْبَىٰ مِنْ أُمَّةٍ ۚ إِنَّمَا يَبْلُوكُمُ ٱللَّهُ بِهِۦ ۚ وَلَيُبَيِّنَنَّ لَكُمْ يَوْمَ ٱلْقِيَـٰمَةِ مَا كُنتُمْ فِيهِ تَخْتَلِفُونَ","en":"And do not be like she who untwisted her spun thread after it was strong [by] taking your oaths as [means of] deceit between you because one community is more plentiful [in number or wealth] than another community.1 Allāh only tries you thereby. And He will surely make clear to you on the Day of Resurrection that over which you used to differ.","tr":"Wala takoonoo kallatee naqadatghazlaha min baAAdi quwwatin ankathan tattakhithoonaaymanakum dakhalan baynakum an takoona ommatun hiya arbamin ommatin innama yablookumu Allahu bihiwalayubayyinanna lakum yawma alqiyamati ma kuntumfeehi takhtalifoon","juz":14,"page":277},{"s":16,"a":93,"key":"16:93","ar":"وَلَوْ شَآءَ ٱللَّهُ لَجَعَلَكُمْ أُمَّةً وَٰحِدَةً وَلَـٰكِن يُضِلُّ مَن يَشَآءُ وَيَهْدِى مَن يَشَآءُ ۚ وَلَتُسْـَٔلُنَّ عَمَّا كُنتُمْ تَعْمَلُونَ","en":"And if Allāh had willed, He could have made you [of] one religion, but He sends astray whom He wills and guides whom He wills.1 And you will surely be questioned about what you used to do.","tr":"Walaw shaa Allahu lajaAAalakumommatan wahidatan walakin yudillu man yashaowayahdee man yashao walatus-alunna AAamma kuntumtaAAmaloon","juz":14,"page":277},{"s":16,"a":94,"key":"16:94","ar":"وَلَا تَتَّخِذُوٓا۟ أَيْمَـٰنَكُمْ دَخَلًۢا بَيْنَكُمْ فَتَزِلَّ قَدَمٌۢ بَعْدَ ثُبُوتِهَا وَتَذُوقُوا۟ ٱلسُّوٓءَ بِمَا صَدَدتُّمْ عَن سَبِيلِ ٱللَّهِ ۖ وَلَكُمْ عَذَابٌ عَظِيمٌ","en":"And do not take your oaths as [means of] deceit between you, lest a foot slip after it was [once] firm, and you would taste evil [in this world] for what [people] you diverted from the way of Allāh,1 and you would have [in the Hereafter] a great punishment.","tr":"Wala tattakhithoo aymanakumdakhalan baynakum fatazilla qadamun baAAda thubootiha watathooqooassoo-a bima sadadtum AAan sabeeli Allahiwalakum AAathabun AAatheem","juz":14,"page":278},{"s":16,"a":95,"key":"16:95","ar":"وَلَا تَشْتَرُوا۟ بِعَهْدِ ٱللَّهِ ثَمَنًا قَلِيلًا ۚ إِنَّمَا عِندَ ٱللَّهِ هُوَ خَيْرٌ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ","en":"And do not exchange the covenant of Allāh for a small price. Indeed, what is with Allāh is best for you, if only you could know.","tr":"Wala tashtaroo biAAahdi Allahithamanan qaleelan innama AAinda Allahi huwa khayrunlakum in kuntum taAAlamoon","juz":14,"page":278},{"s":16,"a":96,"key":"16:96","ar":"مَا عِندَكُمْ يَنفَدُ ۖ وَمَا عِندَ ٱللَّهِ بَاقٍ ۗ وَلَنَجْزِيَنَّ ٱلَّذِينَ صَبَرُوٓا۟ أَجْرَهُم بِأَحْسَنِ مَا كَانُوا۟ يَعْمَلُونَ","en":"Whatever you have will end, but what Allāh has is lasting. And We will surely give those who were patient their reward according to the best of what they used to do.","tr":"Ma AAindakum yanfadu wamaAAinda Allahi baqin walanajziyanna allatheenasabaroo ajrahum bi-ahsani ma kanooyaAAmaloon","juz":14,"page":278},{"s":16,"a":97,"key":"16:97","ar":"مَنْ عَمِلَ صَـٰلِحًا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ فَلَنُحْيِيَنَّهُۥ حَيَوٰةً طَيِّبَةً ۖ وَلَنَجْزِيَنَّهُمْ أَجْرَهُم بِأَحْسَنِ مَا كَانُوا۟ يَعْمَلُونَ","en":"Whoever does righteousness, whether male or female, while he is a believer - We will surely cause him to live a good life, and We will surely give them their reward [in the Hereafter] according to the best of what they used to do.","tr":"Man AAamila salihan min thakarinaw ontha wahuwa mu/minun falanuhyiyannahu hayatantayyibatan walanajziyannahum ajrahum bi-ahsani makanoo yaAAmaloon","juz":14,"page":278},{"s":16,"a":98,"key":"16:98","ar":"فَإِذَا قَرَأْتَ ٱلْقُرْءَانَ فَٱسْتَعِذْ بِٱللَّهِ مِنَ ٱلشَّيْطَـٰنِ ٱلرَّجِيمِ","en":"So when you recite the Qur’ān, [first] seek refuge in Allāh from Satan, the expelled [from His mercy].","tr":"Fa-itha qara/ta alqur-ana fastaAAithbillahi mina ashshaytani arrajeem","juz":14,"page":278},{"s":16,"a":99,"key":"16:99","ar":"إِنَّهُۥ لَيْسَ لَهُۥ سُلْطَـٰنٌ عَلَى ٱلَّذِينَ ءَامَنُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ","en":"Indeed, there is for him no authority over those who have believed and rely upon their Lord.","tr":"Innahu laysa lahu sultanun AAalaallatheena amanoo waAAala rabbihimyatawakkaloon","juz":14,"page":278},{"s":16,"a":100,"key":"16:100","ar":"إِنَّمَا سُلْطَـٰنُهُۥ عَلَى ٱلَّذِينَ يَتَوَلَّوْنَهُۥ وَٱلَّذِينَ هُم بِهِۦ مُشْرِكُونَ","en":"His authority is only over those who take him as an ally and those who through him associate others with Allāh.","tr":"Innama sultanuhu AAalaallatheena yatawallawnahu wallatheena humbihi mushrikoon","juz":14,"page":278},{"s":16,"a":101,"key":"16:101","ar":"وَإِذَا بَدَّلْنَآ ءَايَةً مَّكَانَ ءَايَةٍ ۙ وَٱللَّهُ أَعْلَمُ بِمَا يُنَزِّلُ قَالُوٓا۟ إِنَّمَآ أَنتَ مُفْتَرٍۭ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ","en":"And when We substitute a verse in place of a verse - and Allāh is most knowing of what He sends down - they say, \"You, [O Muḥammad], are but an inventor [of lies].\" But most of them do not know.","tr":"Wa-itha baddalna ayatanmakana ayatin wallahu aAAlamu bimayunazzilu qaloo innama anta muftarin bal aktharuhumla yaAAlamoon","juz":14,"page":278},{"s":16,"a":102,"key":"16:102","ar":"قُلْ نَزَّلَهُۥ رُوحُ ٱلْقُدُسِ مِن رَّبِّكَ بِٱلْحَقِّ لِيُثَبِّتَ ٱلَّذِينَ ءَامَنُوا۟ وَهُدًى وَبُشْرَىٰ لِلْمُسْلِمِينَ","en":"Say, [O Muḥammad], \"The Pure Spirit [i.e., Gabriel] has brought it down from your Lord in truth to make firm those who believe and as guidance and good tidings to the Muslims.\"","tr":"Qul nazzalahu roohu alqudusi minrabbika bilhaqqi liyuthabbita allatheena amanoowahudan wabushra lilmuslimeen","juz":14,"page":278},{"s":16,"a":103,"key":"16:103","ar":"وَلَقَدْ نَعْلَمُ أَنَّهُمْ يَقُولُونَ إِنَّمَا يُعَلِّمُهُۥ بَشَرٌ ۗ لِّسَانُ ٱلَّذِى يُلْحِدُونَ إِلَيْهِ أَعْجَمِىٌّ وَهَـٰذَا لِسَانٌ عَرَبِىٌّ مُّبِينٌ","en":"And We certainly know that they say, \"It is only a human being who teaches him [i.e., the Prophet (ﷺ)].\" The tongue of the one they refer to is foreign,1 and this [recitation, i.e., Qur’ān] is [in] a clear Arabic language.","tr":"Walaqad naAAlamu annahum yaqooloona innamayuAAallimuhu basharun lisanu allathee yulhidoonailayhi aAAjamiyyun wahatha lisanun AAarabiyyunmubeen","juz":14,"page":279},{"s":16,"a":104,"key":"16:104","ar":"إِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِـَٔايَـٰتِ ٱللَّهِ لَا يَهْدِيهِمُ ٱللَّهُ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"Indeed, those who do not believe in the verses of Allāh - Allāh will not guide them, and for them is a painful punishment.","tr":"Inna allatheena la yu/minoonabi-ayati Allahi la yahdeehimu Allahuwalahum AAathabun aleem","juz":14,"page":279},{"s":16,"a":105,"key":"16:105","ar":"إِنَّمَا يَفْتَرِى ٱلْكَذِبَ ٱلَّذِينَ لَا يُؤْمِنُونَ بِـَٔايَـٰتِ ٱللَّهِ ۖ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْكَـٰذِبُونَ","en":"They only invent falsehood who do not believe in the verses of Allāh, and it is those who are the liars.","tr":"Innama yaftaree alkathibaallatheena la yu/minoona bi-ayati Allahiwaola-ika humu alkathiboon","juz":14,"page":279},{"s":16,"a":106,"key":"16:106","ar":"مَن كَفَرَ بِٱللَّهِ مِنۢ بَعْدِ إِيمَـٰنِهِۦٓ إِلَّا مَنْ أُكْرِهَ وَقَلْبُهُۥ مُطْمَئِنٌّۢ بِٱلْإِيمَـٰنِ وَلَـٰكِن مَّن شَرَحَ بِٱلْكُفْرِ صَدْرًا فَعَلَيْهِمْ غَضَبٌ مِّنَ ٱللَّهِ وَلَهُمْ عَذَابٌ عَظِيمٌ","en":"Whoever disbelieves in [i.e., denies] Allāh after his belief...1 except for one who is forced [to renounce his religion] while his heart is secure in faith. But those who [willingly] open their breasts to disbelief, upon them is wrath from Allāh, and for them is a great punishment;","tr":"Man kafara billahi minbaAAdi eemanihi illa man okriha waqalbuhu mutma-innunbil-eemani walakin man sharaha bilkufrisadran faAAalayhim ghadabun mina Allahiwalahum AAathabun AAatheem","juz":14,"page":279},{"s":16,"a":107,"key":"16:107","ar":"ذَٰلِكَ بِأَنَّهُمُ ٱسْتَحَبُّوا۟ ٱلْحَيَوٰةَ ٱلدُّنْيَا عَلَى ٱلْـَٔاخِرَةِ وَأَنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلْكَـٰفِرِينَ","en":"That is because they preferred the worldly life over the Hereafter and that Allāh does not guide the disbelieving people.","tr":"Thalika bi-annahumu istahabbooalhayata addunya AAala al-akhiratiwaanna Allaha la yahdee alqawma alkafireen","juz":14,"page":279},{"s":16,"a":108,"key":"16:108","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ طَبَعَ ٱللَّهُ عَلَىٰ قُلُوبِهِمْ وَسَمْعِهِمْ وَأَبْصَـٰرِهِمْ ۖ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْغَـٰفِلُونَ","en":"Those are the ones over whose hearts and hearing and vision Allāh has sealed, and it is those who are the heedless.","tr":"Ola-ika allatheena tabaAAaAllahu AAala quloobihim wasamAAihim waabsarihimwaola-ika humu alghafiloon","juz":14,"page":279},{"s":16,"a":109,"key":"16:109","ar":"لَا جَرَمَ أَنَّهُمْ فِى ٱلْـَٔاخِرَةِ هُمُ ٱلْخَـٰسِرُونَ","en":"Assuredly, it is they, in the Hereafter, who will be the losers.","tr":"La jarama annahum fee al-akhiratihumu alkhasiroon","juz":14,"page":279},{"s":16,"a":110,"key":"16:110","ar":"ثُمَّ إِنَّ رَبَّكَ لِلَّذِينَ هَاجَرُوا۟ مِنۢ بَعْدِ مَا فُتِنُوا۟ ثُمَّ جَـٰهَدُوا۟ وَصَبَرُوٓا۟ إِنَّ رَبَّكَ مِنۢ بَعْدِهَا لَغَفُورٌ رَّحِيمٌ","en":"Then, indeed your Lord, to those who emigrated after they had been compelled [to say words of disbelief] and thereafter fought [for the cause of Allāh] and were patient - indeed, your Lord, after that, is Forgiving and Merciful","tr":"Thumma inna rabbaka lillatheena hajaroomin baAAdi ma futinoo thumma jahadoo wasabarooinna rabbaka min baAAdiha laghafoorun raheem","juz":14,"page":279},{"s":16,"a":111,"key":"16:111","ar":"۞ يَوْمَ تَأْتِى كُلُّ نَفْسٍ تُجَـٰدِلُ عَن نَّفْسِهَا وَتُوَفَّىٰ كُلُّ نَفْسٍ مَّا عَمِلَتْ وَهُمْ لَا يُظْلَمُونَ","en":"On the Day when every soul will come disputing [i.e., pleading] for itself, and every soul will be fully compensated for what it did, and they will not be wronged [i.e., treated unjustly].","tr":"Yawma ta/tee kullu nafsin tujadiluAAan nafsiha watuwaffa kullu nafsin maAAamilat wahum la yuthlamoon","juz":14,"page":280},{"s":16,"a":112,"key":"16:112","ar":"وَضَرَبَ ٱللَّهُ مَثَلًا قَرْيَةً كَانَتْ ءَامِنَةً مُّطْمَئِنَّةً يَأْتِيهَا رِزْقُهَا رَغَدًا مِّن كُلِّ مَكَانٍ فَكَفَرَتْ بِأَنْعُمِ ٱللَّهِ فَأَذَٰقَهَا ٱللَّهُ لِبَاسَ ٱلْجُوعِ وَٱلْخَوْفِ بِمَا كَانُوا۟ يَصْنَعُونَ","en":"And Allāh presents an example: a city [i.e., Makkah] which was safe and secure, its provision coming to it in abundance from every location, but it denied the favors of Allāh. So Allāh made it taste the envelopment of hunger and fear for what they had been doing.","tr":"Wadaraba Allahu mathalanqaryatan kanat aminatan mutma-innatanya/teeha rizquha raghadan min kulli makaninfakafarat bi-anAAumi Allahi faathaqaha Allahulibasa aljooAAi walkhawfi bima kanooyasnaAAoon","juz":14,"page":280},{"s":16,"a":113,"key":"16:113","ar":"وَلَقَدْ جَآءَهُمْ رَسُولٌ مِّنْهُمْ فَكَذَّبُوهُ فَأَخَذَهُمُ ٱلْعَذَابُ وَهُمْ ظَـٰلِمُونَ","en":"And there had certainly come to them a Messenger from among themselves, but they denied him; so punishment overtook them while they were wrongdoers.","tr":"Walaqad jaahum rasoolun minhum fakaththaboohufaakhathahumu alAAathabu wahum thalimoon","juz":14,"page":280},{"s":16,"a":114,"key":"16:114","ar":"فَكُلُوا۟ مِمَّا رَزَقَكُمُ ٱللَّهُ حَلَـٰلًا طَيِّبًا وَٱشْكُرُوا۟ نِعْمَتَ ٱللَّهِ إِن كُنتُمْ إِيَّاهُ تَعْبُدُونَ","en":"Then eat of what Allāh has provided for you [which is] lawful and good. And be grateful for the favor of Allāh, if it is [indeed] Him that you worship.","tr":"Fakuloo mimma razaqakumu Allahuhalalan tayyiban washkuroo niAAmataAllahi in kuntum iyyahu taAAbudoon","juz":14,"page":280},{"s":16,"a":115,"key":"16:115","ar":"إِنَّمَا حَرَّمَ عَلَيْكُمُ ٱلْمَيْتَةَ وَٱلدَّمَ وَلَحْمَ ٱلْخِنزِيرِ وَمَآ أُهِلَّ لِغَيْرِ ٱللَّهِ بِهِۦ ۖ فَمَنِ ٱضْطُرَّ غَيْرَ بَاغٍ وَلَا عَادٍ فَإِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"He has only forbidden to you dead animals,1 blood, the flesh of swine, and that which has been dedicated to other than Allāh. But whoever is forced [by necessity], neither desiring [it] nor transgressing [its limit] - then indeed, Allāh is Forgiving and Merciful.","tr":"Innama harrama AAalaykumualmaytata waddama walahma alkhinzeeri wamaohilla lighayri Allahi bihi famani idturra ghayra baghinwala AAadin fa-inna Allaha ghafoorun raheem","juz":14,"page":280},{"s":16,"a":116,"key":"16:116","ar":"وَلَا تَقُولُوا۟ لِمَا تَصِفُ أَلْسِنَتُكُمُ ٱلْكَذِبَ هَـٰذَا حَلَـٰلٌ وَهَـٰذَا حَرَامٌ لِّتَفْتَرُوا۟ عَلَى ٱللَّهِ ٱلْكَذِبَ ۚ إِنَّ ٱلَّذِينَ يَفْتَرُونَ عَلَى ٱللَّهِ ٱلْكَذِبَ لَا يُفْلِحُونَ","en":"And do not say about what your tongues assert of untruth, \"This is lawful and this is unlawful,\" to invent falsehood about Allāh. Indeed, those who invent falsehood about Allāh will not succeed.","tr":"Wala taqooloo lima tasifualsinatukumu alkathiba hatha halalunwahatha haramun litaftaroo AAala Allahialkathiba inna allatheena yaftaroona AAalaAllahi alkathiba la yuflihoon","juz":14,"page":280},{"s":16,"a":117,"key":"16:117","ar":"مَتَـٰعٌ قَلِيلٌ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"[It is but] a brief enjoyment, and they will have a painful punishment.","tr":"MataAAun qaleelun walahum AAathabunaleem","juz":14,"page":280},{"s":16,"a":118,"key":"16:118","ar":"وَعَلَى ٱلَّذِينَ هَادُوا۟ حَرَّمْنَا مَا قَصَصْنَا عَلَيْكَ مِن قَبْلُ ۖ وَمَا ظَلَمْنَـٰهُمْ وَلَـٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ","en":"And to those who are Jews We have prohibited that which We related to you before.1 And We did not wrong them [thereby], but they were wronging themselves.","tr":"WaAAala allatheena hadooharramna ma qasasnaAAalayka min qablu wama thalamnahumwalakin kanoo anfusahum yathlimoon","juz":14,"page":280},{"s":16,"a":119,"key":"16:119","ar":"ثُمَّ إِنَّ رَبَّكَ لِلَّذِينَ عَمِلُوا۟ ٱلسُّوٓءَ بِجَهَـٰلَةٍ ثُمَّ تَابُوا۟ مِنۢ بَعْدِ ذَٰلِكَ وَأَصْلَحُوٓا۟ إِنَّ رَبَّكَ مِنۢ بَعْدِهَا لَغَفُورٌ رَّحِيمٌ","en":"Then, indeed your Lord, to those who have done wrong out of ignorance and then repent after that and correct themselves - indeed, your Lord, thereafter, is Forgiving and Merciful.","tr":"Thumma inna rabbaka lillatheenaAAamiloo assoo-a bijahalatin thumma taboomin baAAdi thalika waaslahoo inna rabbakamin baAAdiha laghafoorun raheem","juz":14,"page":281},{"s":16,"a":120,"key":"16:120","ar":"إِنَّ إِبْرَٰهِيمَ كَانَ أُمَّةً قَانِتًا لِّلَّهِ حَنِيفًا وَلَمْ يَكُ مِنَ ٱلْمُشْرِكِينَ","en":"Indeed, Abraham was a [comprehensive] leader,1 devoutly obedient to Allāh, inclining toward truth, and he was not of those who associate others with Allāh.","tr":"Inna ibraheema kana ommatan qanitanlillahi haneefan walam yaku mina almushrikeen","juz":14,"page":281},{"s":16,"a":121,"key":"16:121","ar":"شَاكِرًا لِّأَنْعُمِهِ ۚ ٱجْتَبَىٰهُ وَهَدَىٰهُ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"[He was] grateful for His favors. He [i.e., Allāh] chose him and guided him to a straight path.","tr":"Shakiran li-anAAumihi ijtabahuwahadahu ila siratin mustaqeem","juz":14,"page":281},{"s":16,"a":122,"key":"16:122","ar":"وَءَاتَيْنَـٰهُ فِى ٱلدُّنْيَا حَسَنَةً ۖ وَإِنَّهُۥ فِى ٱلْـَٔاخِرَةِ لَمِنَ ٱلصَّـٰلِحِينَ","en":"And We gave him good in this world, and indeed, in the Hereafter he will be among the righteous.","tr":"Waataynahu fee addunyahasanatan wa-innahu fee al-akhirati lamina assaliheen","juz":14,"page":281},{"s":16,"a":123,"key":"16:123","ar":"ثُمَّ أَوْحَيْنَآ إِلَيْكَ أَنِ ٱتَّبِعْ مِلَّةَ إِبْرَٰهِيمَ حَنِيفًا ۖ وَمَا كَانَ مِنَ ٱلْمُشْرِكِينَ","en":"Then We revealed to you, [O Muḥammad], to follow the religion of Abraham, inclining toward truth; and he was not of those who associate with Allāh.","tr":"Thumma awhayna ilayka aniittabiAA millata ibraheema haneefan wama kanamina almushrikeen","juz":14,"page":281},{"s":16,"a":124,"key":"16:124","ar":"إِنَّمَا جُعِلَ ٱلسَّبْتُ عَلَى ٱلَّذِينَ ٱخْتَلَفُوا۟ فِيهِ ۚ وَإِنَّ رَبَّكَ لَيَحْكُمُ بَيْنَهُمْ يَوْمَ ٱلْقِيَـٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ","en":"The sabbath was only appointed for those who differed over it. And indeed, your Lord will judge between them on the Day of Resurrection concerning that over which they used to differ.","tr":"Innama juAAila assabtu AAalaallatheena ikhtalafoo feehi wa-inna rabbaka layahkumubaynahum yawma alqiyamati feema kanoo feehiyakhtalifoon","juz":14,"page":281},{"s":16,"a":125,"key":"16:125","ar":"ٱدْعُ إِلَىٰ سَبِيلِ رَبِّكَ بِٱلْحِكْمَةِ وَٱلْمَوْعِظَةِ ٱلْحَسَنَةِ ۖ وَجَـٰدِلْهُم بِٱلَّتِى هِىَ أَحْسَنُ ۚ إِنَّ رَبَّكَ هُوَ أَعْلَمُ بِمَن ضَلَّ عَن سَبِيلِهِۦ ۖ وَهُوَ أَعْلَمُ بِٱلْمُهْتَدِينَ","en":"Invite to the way of your Lord with wisdom and good instruction, and argue with them in a way that is best. Indeed, your Lord is most knowing of who has strayed from His way, and He is most knowing of who is [rightly] guided.","tr":"OdAAu ila sabeeli rabbika bilhikmatiwalmawAAithati alhasanati wajadilhumbillatee hiya ahsanu inna rabbaka huwa aAAlamubiman dalla AAan sabeelihi wahuwa aAAlamu bilmuhtadeen","juz":14,"page":281},{"s":16,"a":126,"key":"16:126","ar":"وَإِنْ عَاقَبْتُمْ فَعَاقِبُوا۟ بِمِثْلِ مَا عُوقِبْتُم بِهِۦ ۖ وَلَئِن صَبَرْتُمْ لَهُوَ خَيْرٌ لِّلصَّـٰبِرِينَ","en":"And if you punish [an enemy, O believers], punish with an equivalent of that with which you were harmed.1 But if you are patient - it is better for those who are patient.","tr":"Wa-in AAaqabtum faAAaqiboobimithli ma AAooqibtum bihi wala-in sabartum lahuwakhayrun lissabireen","juz":14,"page":281},{"s":16,"a":127,"key":"16:127","ar":"وَٱصْبِرْ وَمَا صَبْرُكَ إِلَّا بِٱللَّهِ ۚ وَلَا تَحْزَنْ عَلَيْهِمْ وَلَا تَكُ فِى ضَيْقٍ مِّمَّا يَمْكُرُونَ","en":"And be patient, [O Muḥammad], and your patience is not but through Allāh. And do not grieve over them and do not be in distress over what they conspire.","tr":"Wasbir wama sabrukailla billahi wala tahzanAAalayhim wala taku fee dayqin mimmayamkuroon","juz":14,"page":281},{"s":16,"a":128,"key":"16:128","ar":"إِنَّ ٱللَّهَ مَعَ ٱلَّذِينَ ٱتَّقَوا۟ وَّٱلَّذِينَ هُم مُّحْسِنُونَ","en":"Indeed, Allāh is with those who fear Him and those who are doers of good.","tr":"Inna Allaha maAAa allatheenaittaqaw wallatheena hum muhsinoon","juz":14,"page":281},{"s":17,"a":1,"key":"17:1","ar":" سُبْحَـٰنَ ٱلَّذِىٓ أَسْرَىٰ بِعَبْدِهِۦ لَيْلًا مِّنَ ٱلْمَسْجِدِ ٱلْحَرَامِ إِلَى ٱلْمَسْجِدِ ٱلْأَقْصَا ٱلَّذِى بَـٰرَكْنَا حَوْلَهُۥ لِنُرِيَهُۥ مِنْ ءَايَـٰتِنَآ ۚ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ","en":"Exalted1 is He who took His Servant [i.e., Prophet Muḥammad (ﷺ)] by night from al-Masjid al-Ḥarām to al-Masjid al-Aqṣā,2 whose surroundings We have blessed, to show him of Our signs. Indeed, He is the Hearing,3 the Seeing.4","tr":"Subhana allathee asrabiAAabdihi laylan mina almasjidi alharami ilaalmasjidi al-aqsa allathee barakna hawlahulinuriyahu min ayatina innahu huwa assameeAAualbaseer","juz":15,"page":282},{"s":17,"a":2,"key":"17:2","ar":"وَءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ وَجَعَلْنَـٰهُ هُدًى لِّبَنِىٓ إِسْرَٰٓءِيلَ أَلَّا تَتَّخِذُوا۟ مِن دُونِى وَكِيلًا","en":"And We gave Moses the Scripture and made it a guidance for the Children of Israel that you not take other than Me as Disposer of affairs,1","tr":"Waatayna moosa alkitabawajaAAalnahu hudan libanee isra-eela allatattakhithoo min doonee wakeela","juz":15,"page":282},{"s":17,"a":3,"key":"17:3","ar":"ذُرِّيَّةَ مَنْ حَمَلْنَا مَعَ نُوحٍ ۚ إِنَّهُۥ كَانَ عَبْدًا شَكُورًا","en":"O descendants of those We carried [in the ship] with Noah. Indeed, he was a grateful servant.","tr":"Thurriyyata man hamalnamaAAa noohin innahu kana AAabdan shakoora","juz":15,"page":282},{"s":17,"a":4,"key":"17:4","ar":"وَقَضَيْنَآ إِلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ فِى ٱلْكِتَـٰبِ لَتُفْسِدُنَّ فِى ٱلْأَرْضِ مَرَّتَيْنِ وَلَتَعْلُنَّ عُلُوًّا كَبِيرًا","en":"And We conveyed1 to the Children of Israel in the Scripture that, \"You will surely cause corruption on the earth twice, and you will surely reach [a degree of] great haughtiness.\"","tr":"Waqadayna ila banee isra-eelafee alkitabi latufsidunna fee al-ardi marratayniwalataAAlunna AAuluwwan kabeera","juz":15,"page":282},{"s":17,"a":5,"key":"17:5","ar":"فَإِذَا جَآءَ وَعْدُ أُولَىٰهُمَا بَعَثْنَا عَلَيْكُمْ عِبَادًا لَّنَآ أُو۟لِى بَأْسٍ شَدِيدٍ فَجَاسُوا۟ خِلَـٰلَ ٱلدِّيَارِ ۚ وَكَانَ وَعْدًا مَّفْعُولًا","en":"So when the [time of] promise came for the first of them,1 We sent against you servants of Ours - those of great military might, and they probed [even] into the homes,2 and it was a promise fulfilled.","tr":"Fa-itha jaa waAAdu oolahumabaAAathna AAalaykum AAibadan lana oleeba/sin shadeedin fajasoo khilala addiyariwakana waAAdan mafAAoola","juz":15,"page":282},{"s":17,"a":6,"key":"17:6","ar":"ثُمَّ رَدَدْنَا لَكُمُ ٱلْكَرَّةَ عَلَيْهِمْ وَأَمْدَدْنَـٰكُم بِأَمْوَٰلٍ وَبَنِينَ وَجَعَلْنَـٰكُمْ أَكْثَرَ نَفِيرًا","en":"Then We gave back to you a return victory over them. And We reinforced you with wealth and sons and made you more numerous in manpower.","tr":"Thumma radadna lakumu alkarrataAAalayhim waamdadnakum bi-amwalin wabaneenawajaAAalnakum akthara nafeera","juz":15,"page":282},{"s":17,"a":7,"key":"17:7","ar":"إِنْ أَحْسَنتُمْ أَحْسَنتُمْ لِأَنفُسِكُمْ ۖ وَإِنْ أَسَأْتُمْ فَلَهَا ۚ فَإِذَا جَآءَ وَعْدُ ٱلْـَٔاخِرَةِ لِيَسُـۥٓـُٔوا۟ وُجُوهَكُمْ وَلِيَدْخُلُوا۟ ٱلْمَسْجِدَ كَمَا دَخَلُوهُ أَوَّلَ مَرَّةٍ وَلِيُتَبِّرُوا۟ مَا عَلَوْا۟ تَتْبِيرًا","en":"[And said], \"If you do good, you do good for yourselves; and if you do evil, [you do it] to them [i.e., yourselves].\" Then when the final [i.e., second] promise came, [We sent your enemies] to sadden your faces and to enter the masjid [i.e., the temple in Jerusalem], as they entered it the first time, and to destroy what they had taken over with [total] destruction.","tr":"In ahsantum ahsantumli-anfusikum wa-in asa/tum falaha fa-itha jaawaAAdu al-akhirati liyasoo-oo wujoohakum waliyadkhulooalmasjida kama dakhaloohu awwala marratin waliyutabbiroo maAAalaw tatbeera","juz":15,"page":282},{"s":17,"a":8,"key":"17:8","ar":"عَسَىٰ رَبُّكُمْ أَن يَرْحَمَكُمْ ۚ وَإِنْ عُدتُّمْ عُدْنَا ۘ وَجَعَلْنَا جَهَنَّمَ لِلْكَـٰفِرِينَ حَصِيرًا","en":"[Then Allāh said], \"It is expected, [if you repent], that your Lord will have mercy upon you. But if you return [to sin], We will return [to punishment]. And We have made Hell, for the disbelievers, a prison-bed.\"","tr":"AAasa rabbukum an yarhamakumwa-in AAudtum AAudna wajaAAalna jahannama lilkafireenahaseera","juz":15,"page":283},{"s":17,"a":9,"key":"17:9","ar":"إِنَّ هَـٰذَا ٱلْقُرْءَانَ يَهْدِى لِلَّتِى هِىَ أَقْوَمُ وَيُبَشِّرُ ٱلْمُؤْمِنِينَ ٱلَّذِينَ يَعْمَلُونَ ٱلصَّـٰلِحَـٰتِ أَنَّ لَهُمْ أَجْرًا كَبِيرًا","en":"Indeed, this Qur’ān guides to that which is most suitable and gives good tidings to the believers who do righteous deeds that they will have a great reward","tr":"Inna hatha alqur-ana yahdeelillatee hiya aqwamu wayubashshiru almu/mineena allatheenayaAAmaloona assalihati anna lahum ajrankabeera","juz":15,"page":283},{"s":17,"a":10,"key":"17:10","ar":"وَأَنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ أَعْتَدْنَا لَهُمْ عَذَابًا أَلِيمًا","en":"And that those who do not believe in the Hereafter - We have prepared for them a painful punishment.","tr":"Waanna allatheena layu/minoona bil-akhirati aAAtadna lahum AAathabanaleema","juz":15,"page":283},{"s":17,"a":11,"key":"17:11","ar":"وَيَدْعُ ٱلْإِنسَـٰنُ بِٱلشَّرِّ دُعَآءَهُۥ بِٱلْخَيْرِ ۖ وَكَانَ ٱلْإِنسَـٰنُ عَجُولًا","en":"And man supplicates for evil [when angry] as he supplicates for good, and man is ever hasty.1","tr":"WayadAAu al-insanu bishsharriduAAaahu bilkhayri wakana al-insanuAAajoola","juz":15,"page":283},{"s":17,"a":12,"key":"17:12","ar":"وَجَعَلْنَا ٱلَّيْلَ وَٱلنَّهَارَ ءَايَتَيْنِ ۖ فَمَحَوْنَآ ءَايَةَ ٱلَّيْلِ وَجَعَلْنَآ ءَايَةَ ٱلنَّهَارِ مُبْصِرَةً لِّتَبْتَغُوا۟ فَضْلًا مِّن رَّبِّكُمْ وَلِتَعْلَمُوا۟ عَدَدَ ٱلسِّنِينَ وَٱلْحِسَابَ ۚ وَكُلَّ شَىْءٍ فَصَّلْنَـٰهُ تَفْصِيلًا","en":"And We have made the night and day two signs, and We erased the sign of the night and made the sign of the day visible1 that you may seek bounty from your Lord and may know the number of years and the account [of time]. And everything We have set out in detail.","tr":"WajaAAalna allayla wannaharaayatayni famahawna ayata allayliwajaAAalna ayata annahari mubsiratanlitabtaghoo fadlan min rabbikum walitaAAlamoo AAadada assineenawalhisaba wakulla shay-in fassalnahutafseela","juz":15,"page":283},{"s":17,"a":13,"key":"17:13","ar":"وَكُلَّ إِنسَـٰنٍ أَلْزَمْنَـٰهُ طَـٰٓئِرَهُۥ فِى عُنُقِهِۦ ۖ وَنُخْرِجُ لَهُۥ يَوْمَ ٱلْقِيَـٰمَةِ كِتَـٰبًا يَلْقَىٰهُ مَنشُورًا","en":"And [for] every person We have imposed his fate upon his neck,1 and We will produce for him on the Day of Resurrection a record which he will encounter spread open.","tr":"Wakulla insanin alzamnahu ta-irahufee AAunuqihi wanukhriju lahu yawma alqiyamati kitabanyalqahu manshoora","juz":15,"page":283},{"s":17,"a":14,"key":"17:14","ar":"ٱقْرَأْ كِتَـٰبَكَ كَفَىٰ بِنَفْسِكَ ٱلْيَوْمَ عَلَيْكَ حَسِيبًا","en":"[It will be said], \"Read your record. Sufficient is yourself against you this Day as accountant.\"","tr":"Iqra/ kitabaka kafa binafsikaalyawma AAalayka haseeba","juz":15,"page":283},{"s":17,"a":15,"key":"17:15","ar":"مَّنِ ٱهْتَدَىٰ فَإِنَّمَا يَهْتَدِى لِنَفْسِهِۦ ۖ وَمَن ضَلَّ فَإِنَّمَا يَضِلُّ عَلَيْهَا ۚ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَىٰ ۗ وَمَا كُنَّا مُعَذِّبِينَ حَتَّىٰ نَبْعَثَ رَسُولًا","en":"Whoever is guided is only guided for [the benefit of] his soul. And whoever errs only errs against it. And no bearer of burdens will bear the burden of another. And never would We punish until We sent a messenger.","tr":"Mani ihtada fa-innama yahtadeelinafsihi waman dalla fa-innama yadilluAAalayha wala taziru waziratun wizra okhrawama kunna muAAaththibeena hattanabAAatha rasoola","juz":15,"page":283},{"s":17,"a":16,"key":"17:16","ar":"وَإِذَآ أَرَدْنَآ أَن نُّهْلِكَ قَرْيَةً أَمَرْنَا مُتْرَفِيهَا فَفَسَقُوا۟ فِيهَا فَحَقَّ عَلَيْهَا ٱلْقَوْلُ فَدَمَّرْنَـٰهَا تَدْمِيرًا","en":"And when We intend to destroy a city, We command its affluent1 but they defiantly disobey therein; so the word [i.e., deserved decree] comes into effect upon it, and We destroy it with [complete] destruction.","tr":"Wa-itha aradna an nuhlikaqaryatan amarna mutrafeeha fafasaqoo feehafahaqqa AAalayha alqawlu fadammarnahatadmeera","juz":15,"page":283},{"s":17,"a":17,"key":"17:17","ar":"وَكَمْ أَهْلَكْنَا مِنَ ٱلْقُرُونِ مِنۢ بَعْدِ نُوحٍ ۗ وَكَفَىٰ بِرَبِّكَ بِذُنُوبِ عِبَادِهِۦ خَبِيرًۢا بَصِيرًا","en":"And how many have We destroyed from the generations after Noah. And sufficient is your Lord, concerning the sins of His servants, as Aware and Seeing.","tr":"Wakam ahlakna mina alqurooni minbaAAdi noohin wakafa birabbika bithunoobiAAibadihi khabeeran baseera","juz":15,"page":283},{"s":17,"a":18,"key":"17:18","ar":"مَّن كَانَ يُرِيدُ ٱلْعَاجِلَةَ عَجَّلْنَا لَهُۥ فِيهَا مَا نَشَآءُ لِمَن نُّرِيدُ ثُمَّ جَعَلْنَا لَهُۥ جَهَنَّمَ يَصْلَىٰهَا مَذْمُومًا مَّدْحُورًا","en":"Whoever should desire the immediate1 - We hasten for him from it what We will to whom We intend. Then We have made for him Hell, which he will [enter to] burn, censured and banished.","tr":"Man kana yureedu alAAajilataAAajjalna lahu feeha ma nashao limannureedu thumma jaAAalna lahu jahannama yaslahamathmooman madhoora","juz":15,"page":284},{"s":17,"a":19,"key":"17:19","ar":"وَمَنْ أَرَادَ ٱلْـَٔاخِرَةَ وَسَعَىٰ لَهَا سَعْيَهَا وَهُوَ مُؤْمِنٌ فَأُو۟لَـٰٓئِكَ كَانَ سَعْيُهُم مَّشْكُورًا","en":"But whoever desires the Hereafter and exerts the effort due to it while he is a believer - it is those whose effort is ever appreciated [by Allāh].","tr":"Waman arada al-akhirata wasaAAalaha saAAyaha wahuwa mu/minun faola-ika kanasaAAyuhum mashkoora","juz":15,"page":284},{"s":17,"a":20,"key":"17:20","ar":"كُلًّا نُّمِدُّ هَـٰٓؤُلَآءِ وَهَـٰٓؤُلَآءِ مِنْ عَطَآءِ رَبِّكَ ۚ وَمَا كَانَ عَطَآءُ رَبِّكَ مَحْظُورًا","en":"To each [category] We extend - to these and to those - from the gift of your Lord. And never has the gift of your Lord been restricted.","tr":"Kullan numiddu haola-i wahaola-imin AAata-i rabbika wama kana AAataorabbika mahthoora","juz":15,"page":284},{"s":17,"a":21,"key":"17:21","ar":"ٱنظُرْ كَيْفَ فَضَّلْنَا بَعْضَهُمْ عَلَىٰ بَعْضٍ ۚ وَلَلْـَٔاخِرَةُ أَكْبَرُ دَرَجَـٰتٍ وَأَكْبَرُ تَفْضِيلًا","en":"Look how We have favored [in provision] some of them over others. But the Hereafter is greater in degrees [of difference] and greater in distinction.","tr":"Onthur kayfa faddalnabaAAdahum AAala baAAdin walal-akhiratuakbaru darajatin waakbaru tafdeela","juz":15,"page":284},{"s":17,"a":22,"key":"17:22","ar":"لَّا تَجْعَلْ مَعَ ٱللَّهِ إِلَـٰهًا ءَاخَرَ فَتَقْعُدَ مَذْمُومًا مَّخْذُولًا","en":"Do not make [as equal] with Allāh another deity and [thereby] become censured and forsaken.","tr":"La tajAAal maAAa Allahi ilahanakhara fataqAAuda mathmooman makhthoola","juz":15,"page":284},{"s":17,"a":23,"key":"17:23","ar":"۞ وَقَضَىٰ رَبُّكَ أَلَّا تَعْبُدُوٓا۟ إِلَّآ إِيَّاهُ وَبِٱلْوَٰلِدَيْنِ إِحْسَـٰنًا ۚ إِمَّا يَبْلُغَنَّ عِندَكَ ٱلْكِبَرَ أَحَدُهُمَآ أَوْ كِلَاهُمَا فَلَا تَقُل لَّهُمَآ أُفٍّ وَلَا تَنْهَرْهُمَا وَقُل لَّهُمَا قَوْلًا كَرِيمًا","en":"And your Lord has decreed that you worship not except Him, and to parents, good treatment. Whether one or both of them reach old age [while] with you, say not to them [so much as], \"uff,\"1 and do not repel them but speak to them a noble word.","tr":"Waqada rabbuka alla taAAbudooilla iyyahu wabilwalidayni ihsananimma yablughanna AAindaka alkibara ahaduhumaaw kilahuma fala taqul lahuma offinwala tanharhuma waqul lahuma qawlan kareema","juz":15,"page":284},{"s":17,"a":24,"key":"17:24","ar":"وَٱخْفِضْ لَهُمَا جَنَاحَ ٱلذُّلِّ مِنَ ٱلرَّحْمَةِ وَقُل رَّبِّ ٱرْحَمْهُمَا كَمَا رَبَّيَانِى صَغِيرًا","en":"And lower to them the wing of humility out of mercy and say, \"My Lord, have mercy upon them as they brought me up [when I was] small.\"","tr":"Wakhfid lahuma janahaaththulli mina arrahmati waqulrabbi irhamhuma kama rabbayanee sagheera","juz":15,"page":284},{"s":17,"a":25,"key":"17:25","ar":"رَّبُّكُمْ أَعْلَمُ بِمَا فِى نُفُوسِكُمْ ۚ إِن تَكُونُوا۟ صَـٰلِحِينَ فَإِنَّهُۥ كَانَ لِلْأَوَّٰبِينَ غَفُورًا","en":"Your Lord is most knowing of what is within yourselves. If you should be righteous [in intention] - then indeed He is ever, to the often returning [to Him], Forgiving.1","tr":"Rabbukum aAAlamu bima fee nufoosikumin takoonoo saliheena fa-innahu kana lil-awwabeenaghafoora","juz":15,"page":284},{"s":17,"a":26,"key":"17:26","ar":"وَءَاتِ ذَا ٱلْقُرْبَىٰ حَقَّهُۥ وَٱلْمِسْكِينَ وَٱبْنَ ٱلسَّبِيلِ وَلَا تُبَذِّرْ تَبْذِيرًا","en":"And give the relative his right, and [also] the poor and the traveler, and do not spend wastefully.1","tr":"Waati tha alqurba haqqahuwalmiskeena wabna assabeeli walatubaththir tabtheera","juz":15,"page":284},{"s":17,"a":27,"key":"17:27","ar":"إِنَّ ٱلْمُبَذِّرِينَ كَانُوٓا۟ إِخْوَٰنَ ٱلشَّيَـٰطِينِ ۖ وَكَانَ ٱلشَّيْطَـٰنُ لِرَبِّهِۦ كَفُورًا","en":"Indeed, the wasteful are brothers of the devils, and ever has Satan been to his Lord ungrateful.","tr":"Inna almubaththireena kanooikhwana ashshayateeni wakana ashshaytanulirabbihi kafoora","juz":15,"page":284},{"s":17,"a":28,"key":"17:28","ar":"وَإِمَّا تُعْرِضَنَّ عَنْهُمُ ٱبْتِغَآءَ رَحْمَةٍ مِّن رَّبِّكَ تَرْجُوهَا فَقُل لَّهُمْ قَوْلًا مَّيْسُورًا","en":"And if you [must] turn away from them [i.e., the needy] awaiting mercy from your Lord which you expect,1 then speak to them a gentle word.","tr":"Wa-imma tuAAridanna AAanhumuibtighaa rahmatin min rabbika tarjooha faqullahum qawlan maysoora","juz":15,"page":285},{"s":17,"a":29,"key":"17:29","ar":"وَلَا تَجْعَلْ يَدَكَ مَغْلُولَةً إِلَىٰ عُنُقِكَ وَلَا تَبْسُطْهَا كُلَّ ٱلْبَسْطِ فَتَقْعُدَ مَلُومًا مَّحْسُورًا","en":"And do not make your hand [as] chained to your neck1 or extend it completely2 and [thereby] become blamed and insolvent.","tr":"Wala tajAAal yadaka maghloolatan ilaAAunuqika wala tabsutha kulla albastifataqAAuda malooman mahsoora","juz":15,"page":285},{"s":17,"a":30,"key":"17:30","ar":"إِنَّ رَبَّكَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّهُۥ كَانَ بِعِبَادِهِۦ خَبِيرًۢا بَصِيرًا","en":"Indeed, your Lord extends provision for whom He wills and restricts [it]. Indeed He is ever, concerning His servants, Aware and Seeing.","tr":"Inna rabbaka yabsutu arrizqaliman yashao wayaqdiru innahu kana biAAibadihikhabeeran baseera","juz":15,"page":285},{"s":17,"a":31,"key":"17:31","ar":"وَلَا تَقْتُلُوٓا۟ أَوْلَـٰدَكُمْ خَشْيَةَ إِمْلَـٰقٍ ۖ نَّحْنُ نَرْزُقُهُمْ وَإِيَّاكُمْ ۚ إِنَّ قَتْلَهُمْ كَانَ خِطْـًٔا كَبِيرًا","en":"And do not kill your children for fear of poverty. We provide for them and for you. Indeed, their killing is ever a great sin.","tr":"Wala taqtuloo awladakumkhashyata imlaqin nahnu narzuquhum wa-iyyakuminna qatlahum kana khit-an kabeera","juz":15,"page":285},{"s":17,"a":32,"key":"17:32","ar":"وَلَا تَقْرَبُوا۟ ٱلزِّنَىٰٓ ۖ إِنَّهُۥ كَانَ فَـٰحِشَةً وَسَآءَ سَبِيلًا","en":"And do not approach unlawful sexual intercourse.1 Indeed, it is ever an immorality and is evil as a way.","tr":"Wala taqraboo azzinainnahu kana fahishatan wasaa sabeela","juz":15,"page":285},{"s":17,"a":33,"key":"17:33","ar":"وَلَا تَقْتُلُوا۟ ٱلنَّفْسَ ٱلَّتِى حَرَّمَ ٱللَّهُ إِلَّا بِٱلْحَقِّ ۗ وَمَن قُتِلَ مَظْلُومًا فَقَدْ جَعَلْنَا لِوَلِيِّهِۦ سُلْطَـٰنًا فَلَا يُسْرِف فِّى ٱلْقَتْلِ ۖ إِنَّهُۥ كَانَ مَنصُورًا","en":"And do not kill the soul [i.e., person] which Allāh has forbidden, except by right.1 And whoever is killed unjustly - We have given his heir authority,2 but let him not exceed limits in [the matter of] taking life. Indeed, he has been supported [by the law].","tr":"Wala taqtuloo annafsa allateeharrama Allahu illa bilhaqqiwaman qutila mathlooman faqad jaAAalnaliwaliyyihi sultanan fala yusrif fee alqatli innahukana mansoora","juz":15,"page":285},{"s":17,"a":34,"key":"17:34","ar":"وَلَا تَقْرَبُوا۟ مَالَ ٱلْيَتِيمِ إِلَّا بِٱلَّتِى هِىَ أَحْسَنُ حَتَّىٰ يَبْلُغَ أَشُدَّهُۥ ۚ وَأَوْفُوا۟ بِٱلْعَهْدِ ۖ إِنَّ ٱلْعَهْدَ كَانَ مَسْـُٔولًا","en":"And do not approach the property of an orphan, except in the way that is best,1 until he reaches maturity. And fulfill [every] commitment. Indeed, the commitment is ever [that about which one will be] questioned.","tr":"Wala taqraboo mala alyateemiilla billatee hiya ahsanu hattayablugha ashuddahu waawfoo bilAAahdi inna alAAahda kanamas-oola","juz":15,"page":285},{"s":17,"a":35,"key":"17:35","ar":"وَأَوْفُوا۟ ٱلْكَيْلَ إِذَا كِلْتُمْ وَزِنُوا۟ بِٱلْقِسْطَاسِ ٱلْمُسْتَقِيمِ ۚ ذَٰلِكَ خَيْرٌ وَأَحْسَنُ تَأْوِيلًا","en":"And give full measure when you measure, and weigh with an even [i.e., honest] balance. That is the best [way] and best in result.","tr":"Waawfoo alkayla itha kiltum wazinoobilqistasi almustaqeemi thalika khayrun waahsanuta/weela","juz":15,"page":285},{"s":17,"a":36,"key":"17:36","ar":"وَلَا تَقْفُ مَا لَيْسَ لَكَ بِهِۦ عِلْمٌ ۚ إِنَّ ٱلسَّمْعَ وَٱلْبَصَرَ وَٱلْفُؤَادَ كُلُّ أُو۟لَـٰٓئِكَ كَانَ عَنْهُ مَسْـُٔولًا","en":"And do not pursue1 that of which you have no knowledge. Indeed, the hearing, the sight and the heart - about all those [one] will be questioned.","tr":"Wala taqfu ma laysa laka bihiAAilmun inna assamAAa walbasara walfu-adakullu ola-ika kana AAanhu mas-oola","juz":15,"page":285},{"s":17,"a":37,"key":"17:37","ar":"وَلَا تَمْشِ فِى ٱلْأَرْضِ مَرَحًا ۖ إِنَّكَ لَن تَخْرِقَ ٱلْأَرْضَ وَلَن تَبْلُغَ ٱلْجِبَالَ طُولًا","en":"And do not walk upon the earth exultantly. Indeed, you will never tear the earth [apart], and you will never reach the mountains in height.1","tr":"Wala tamshi fee al-ardi marahaninnaka lan takhriqa al-arda walan tablugha aljibalatoola","juz":15,"page":285},{"s":17,"a":38,"key":"17:38","ar":"كُلُّ ذَٰلِكَ كَانَ سَيِّئُهُۥ عِندَ رَبِّكَ مَكْرُوهًا","en":"All that [i.e., the aforementioned] - its evil is ever, in the sight of your Lord, detested.","tr":"Kullu thalika kana sayyi-ohuAAinda rabbika makrooha","juz":15,"page":285},{"s":17,"a":39,"key":"17:39","ar":"ذَٰلِكَ مِمَّآ أَوْحَىٰٓ إِلَيْكَ رَبُّكَ مِنَ ٱلْحِكْمَةِ ۗ وَلَا تَجْعَلْ مَعَ ٱللَّهِ إِلَـٰهًا ءَاخَرَ فَتُلْقَىٰ فِى جَهَنَّمَ مَلُومًا مَّدْحُورًا","en":"That is from what your Lord has revealed to you, [O Muḥammad], of wisdom. And, [O mankind], do not make [as equal] with Allāh another deity, lest you be thrown into Hell, blamed and banished.","tr":"Thalika mimma awhailayka rabbuka mina alhikmati wala tajAAal maAAaAllahi ilahan akhara fatulqa feejahannama malooman madhoora","juz":15,"page":286},{"s":17,"a":40,"key":"17:40","ar":"أَفَأَصْفَىٰكُمْ رَبُّكُم بِٱلْبَنِينَ وَٱتَّخَذَ مِنَ ٱلْمَلَـٰٓئِكَةِ إِنَـٰثًا ۚ إِنَّكُمْ لَتَقُولُونَ قَوْلًا عَظِيمًا","en":"Then, has your Lord chosen you for [having] sons and taken [i.e., adopted] from among the angels daughters? Indeed, you say a grave saying.","tr":"Afaasfakum rabbukum bilbaneenawattakhatha mina almala-ikati inathaninnakum lataqooloona qawlan AAatheema","juz":15,"page":286},{"s":17,"a":41,"key":"17:41","ar":"وَلَقَدْ صَرَّفْنَا فِى هَـٰذَا ٱلْقُرْءَانِ لِيَذَّكَّرُوا۟ وَمَا يَزِيدُهُمْ إِلَّا نُفُورًا","en":"And We have certainly diversified [the contents] in this Qur’ān that they [i.e., mankind] may be reminded, but it does not increase them [i.e., the disbelievers] except in aversion.","tr":"Walaqad sarrafna fee hathaalqur-ani liyaththakkaroo wama yazeeduhumilla nufoora","juz":15,"page":286},{"s":17,"a":42,"key":"17:42","ar":"قُل لَّوْ كَانَ مَعَهُۥٓ ءَالِهَةٌ كَمَا يَقُولُونَ إِذًا لَّٱبْتَغَوْا۟ إِلَىٰ ذِى ٱلْعَرْشِ سَبِيلًا","en":"Say, [O Muḥammad], \"If there had been with Him [other] gods, as they say, then they [each] would have sought to the Owner of the Throne a way.\"1","tr":"Qul law kana maAAahu alihatunkama yaqooloona ithan labtaghaw ila theealAAarshi sabeela","juz":15,"page":286},{"s":17,"a":43,"key":"17:43","ar":"سُبْحَـٰنَهُۥ وَتَعَـٰلَىٰ عَمَّا يَقُولُونَ عُلُوًّا كَبِيرًا","en":"Exalted is He and high above what they say by great sublimity.","tr":"Subhanahu wataAAalaAAamma yaqooloona AAuluwwan kabeera","juz":15,"page":286},{"s":17,"a":44,"key":"17:44","ar":"تُسَبِّحُ لَهُ ٱلسَّمَـٰوَٰتُ ٱلسَّبْعُ وَٱلْأَرْضُ وَمَن فِيهِنَّ ۚ وَإِن مِّن شَىْءٍ إِلَّا يُسَبِّحُ بِحَمْدِهِۦ وَلَـٰكِن لَّا تَفْقَهُونَ تَسْبِيحَهُمْ ۗ إِنَّهُۥ كَانَ حَلِيمًا غَفُورًا","en":"The seven heavens and the earth and whatever is in them exalt Him. And there is not a thing except that it exalts [Allāh] by His praise, but you do not understand their [way of] exalting. Indeed, He is ever Forbearing1 and Forgiving.","tr":"Tusabbihu lahu assamawatuassabAAu wal-ardu waman feehinna wa-in minshay-in illa yusabbihu bihamdihi walakinla tafqahoona tasbeehahum innahu kana haleemanghafoora","juz":15,"page":286},{"s":17,"a":45,"key":"17:45","ar":"وَإِذَا قَرَأْتَ ٱلْقُرْءَانَ جَعَلْنَا بَيْنَكَ وَبَيْنَ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ حِجَابًا مَّسْتُورًا","en":"And when you recite the Qur’ān, We put between you and those who do not believe in the Hereafter a concealed partition.1","tr":"Wa-itha qara/ta alqur-anajaAAalna baynaka wabayna allatheena layu/minoona bil-akhirati hijabanmastoora","juz":15,"page":286},{"s":17,"a":46,"key":"17:46","ar":"وَجَعَلْنَا عَلَىٰ قُلُوبِهِمْ أَكِنَّةً أَن يَفْقَهُوهُ وَفِىٓ ءَاذَانِهِمْ وَقْرًا ۚ وَإِذَا ذَكَرْتَ رَبَّكَ فِى ٱلْقُرْءَانِ وَحْدَهُۥ وَلَّوْا۟ عَلَىٰٓ أَدْبَـٰرِهِمْ نُفُورًا","en":"And We have placed over their hearts coverings, lest they understand it, and in their ears deafness. And when you mention your Lord alone in the Qur’ān, they turn back in aversion.","tr":"WajaAAalna AAala quloobihimakinnatan an yafqahoohu wafee athanihim waqran wa-ithathakarta rabbaka fee alqur-ani wahdahuwallaw AAala adbarihim nufoora","juz":15,"page":286},{"s":17,"a":47,"key":"17:47","ar":"نَّحْنُ أَعْلَمُ بِمَا يَسْتَمِعُونَ بِهِۦٓ إِذْ يَسْتَمِعُونَ إِلَيْكَ وَإِذْ هُمْ نَجْوَىٰٓ إِذْ يَقُولُ ٱلظَّـٰلِمُونَ إِن تَتَّبِعُونَ إِلَّا رَجُلًا مَّسْحُورًا","en":"We are most knowing of how they listen to it when they listen to you and [of] when they are in private conversation, when the wrongdoers say, \"You follow not but a man affected by magic.\"","tr":"Nahnu aAAlamu bimayastamiAAoona bihi ith yastamiAAoona ilayka wa-ithhum najwa ith yaqoolu aththalimoonain tattabiAAoona illa rajulan mashoora","juz":15,"page":286},{"s":17,"a":48,"key":"17:48","ar":"ٱنظُرْ كَيْفَ ضَرَبُوا۟ لَكَ ٱلْأَمْثَالَ فَضَلُّوا۟ فَلَا يَسْتَطِيعُونَ سَبِيلًا","en":"Look how they strike for you comparisons;1 but they have strayed, so they cannot [find] a way.","tr":"Onthur kayfa daraboolaka al-amthala fadalloo fala yastateeAAoonasabeela","juz":15,"page":286},{"s":17,"a":49,"key":"17:49","ar":"وَقَالُوٓا۟ أَءِذَا كُنَّا عِظَـٰمًا وَرُفَـٰتًا أَءِنَّا لَمَبْعُوثُونَ خَلْقًا جَدِيدًا","en":"And they say, \"When we are bones and crumbled particles, will we [truly] be resurrected as a new creation?\"","tr":"Waqaloo a-itha kunnaAAithaman warufatan a-innalamabAAoothoona khalqan jadeeda","juz":15,"page":286},{"s":17,"a":50,"key":"17:50","ar":"۞ قُلْ كُونُوا۟ حِجَارَةً أَوْ حَدِيدًا","en":"Say, \"Be you stones or iron1","tr":"Qul koonoo hijaratan aw hadeeda","juz":15,"page":287},{"s":17,"a":51,"key":"17:51","ar":"أَوْ خَلْقًا مِّمَّا يَكْبُرُ فِى صُدُورِكُمْ ۚ فَسَيَقُولُونَ مَن يُعِيدُنَا ۖ قُلِ ٱلَّذِى فَطَرَكُمْ أَوَّلَ مَرَّةٍ ۚ فَسَيُنْغِضُونَ إِلَيْكَ رُءُوسَهُمْ وَيَقُولُونَ مَتَىٰ هُوَ ۖ قُلْ عَسَىٰٓ أَن يَكُونَ قَرِيبًا","en":"Or [any] creation of that which is great1 within your breasts.\" And they will say, \"Who will restore us?\" Say, \"He who brought you forth the first time.\" Then they will nod their heads toward you2 and say, \"When is that?\" Say, \"Perhaps it will be soon -","tr":"Aw khalqan mimma yakburu fee sudoorikumfasayaqooloona man yuAAeeduna quli allathee fatarakumawwala marratin fasayunghidoona ilayka ruoosahumwayaqooloona mata huwa qul AAasa an yakoona qareeba","juz":15,"page":287},{"s":17,"a":52,"key":"17:52","ar":"يَوْمَ يَدْعُوكُمْ فَتَسْتَجِيبُونَ بِحَمْدِهِۦ وَتَظُنُّونَ إِن لَّبِثْتُمْ إِلَّا قَلِيلًا","en":"On the Day He will call you and you will respond with praise of Him and think that you had not remained [in the world] except for a little.\"","tr":"Yawma yadAAookum fatastajeeboona bihamdihiwatathunnoona in labithtum illa qaleela","juz":15,"page":287},{"s":17,"a":53,"key":"17:53","ar":"وَقُل لِّعِبَادِى يَقُولُوا۟ ٱلَّتِى هِىَ أَحْسَنُ ۚ إِنَّ ٱلشَّيْطَـٰنَ يَنزَغُ بَيْنَهُمْ ۚ إِنَّ ٱلشَّيْطَـٰنَ كَانَ لِلْإِنسَـٰنِ عَدُوًّا مُّبِينًا","en":"And tell My servants to say that which is best. Indeed, Satan induces [dissension] among them. Indeed Satan is ever, to mankind, a clear enemy.","tr":"Waqul liAAibadee yaqooloo allateehiya ahsanu inna ashshaytana yanzaghubaynahum inna ashshaytana kana lil-insaniAAaduwwan mubeena","juz":15,"page":287},{"s":17,"a":54,"key":"17:54","ar":"رَّبُّكُمْ أَعْلَمُ بِكُمْ ۖ إِن يَشَأْ يَرْحَمْكُمْ أَوْ إِن يَشَأْ يُعَذِّبْكُمْ ۚ وَمَآ أَرْسَلْنَـٰكَ عَلَيْهِمْ وَكِيلًا","en":"Your Lord is most knowing of you. If He wills, He will have mercy upon you; or if He wills, He will punish you. And We have not sent you, [O Muḥammad], over them as a manager.","tr":"Rabbukum aAAlamu bikum in yasha/ yarhamkumaw in yasha/ yuAAaththibkum wama arsalnakaAAalayhim wakeela","juz":15,"page":287},{"s":17,"a":55,"key":"17:55","ar":"وَرَبُّكَ أَعْلَمُ بِمَن فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۗ وَلَقَدْ فَضَّلْنَا بَعْضَ ٱلنَّبِيِّـۧنَ عَلَىٰ بَعْضٍ ۖ وَءَاتَيْنَا دَاوُۥدَ زَبُورًا","en":"And your Lord is most knowing of whoever is in the heavens and the earth. And We have made some of the prophets exceed others [in various ways], and to David We gave the book [of Psalms].","tr":"Warabbuka aAAlamu biman fee assamawatiwal-ardi walaqad faddalna baAAdaannabiyyeena AAala baAAdin waataynadawooda zaboora","juz":15,"page":287},{"s":17,"a":56,"key":"17:56","ar":"قُلِ ٱدْعُوا۟ ٱلَّذِينَ زَعَمْتُم مِّن دُونِهِۦ فَلَا يَمْلِكُونَ كَشْفَ ٱلضُّرِّ عَنكُمْ وَلَا تَحْوِيلًا","en":"Say, \"Invoke those you have claimed [as gods] besides Him, for they do not possess the [ability for] removal of adversity from you or [for its] transfer [to someone else].\"","tr":"Quli odAAu allatheena zaAAamtum mindoonihi fala yamlikoona kashfa addurriAAankum wala tahweela","juz":15,"page":287},{"s":17,"a":57,"key":"17:57","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ يَدْعُونَ يَبْتَغُونَ إِلَىٰ رَبِّهِمُ ٱلْوَسِيلَةَ أَيُّهُمْ أَقْرَبُ وَيَرْجُونَ رَحْمَتَهُۥ وَيَخَافُونَ عَذَابَهُۥٓ ۚ إِنَّ عَذَابَ رَبِّكَ كَانَ مَحْذُورًا","en":"Those whom they invoke1 seek means of access to their Lord, [striving as to] which of them would be nearest, and they hope for His mercy and fear His punishment. Indeed, the punishment of your Lord is ever feared.","tr":"Ola-ika allatheena yadAAoonayabtaghoona ila rabbihimu alwaseelata ayyuhum aqrabuwayarjoona rahmatahu wayakhafoona AAathabahuinna AAathaba rabbika kana mahthoora","juz":15,"page":287},{"s":17,"a":58,"key":"17:58","ar":"وَإِن مِّن قَرْيَةٍ إِلَّا نَحْنُ مُهْلِكُوهَا قَبْلَ يَوْمِ ٱلْقِيَـٰمَةِ أَوْ مُعَذِّبُوهَا عَذَابًا شَدِيدًا ۚ كَانَ ذَٰلِكَ فِى ٱلْكِتَـٰبِ مَسْطُورًا","en":"And there is no city but that We will destroy it1 before the Day of Resurrection or punish it with a severe punishment. That has ever been in the Register2 inscribed.","tr":"Wa-in min qaryatin illa nahnumuhlikooha qabla yawmi alqiyamati aw muAAaththiboohaAAathaban shadeedan kana thalika fee alkitabimastoora","juz":15,"page":287},{"s":17,"a":59,"key":"17:59","ar":"وَمَا مَنَعَنَآ أَن نُّرْسِلَ بِٱلْـَٔايَـٰتِ إِلَّآ أَن كَذَّبَ بِهَا ٱلْأَوَّلُونَ ۚ وَءَاتَيْنَا ثَمُودَ ٱلنَّاقَةَ مُبْصِرَةً فَظَلَمُوا۟ بِهَا ۚ وَمَا نُرْسِلُ بِٱلْـَٔايَـٰتِ إِلَّا تَخْوِيفًا","en":"And nothing has prevented Us from sending signs [i.e., miracles] except that the former peoples denied them. And We gave Thamūd the she-camel as a visible sign, but they wronged her. And We send not the signs except as a warning.","tr":"Wama manaAAana an nursila bil-ayatiilla an kaththaba biha al-awwaloona waataynathamooda annaqata mubsiratan fathalamoobiha wama nursilu bil-ayatiilla takhweefa","juz":15,"page":288},{"s":17,"a":60,"key":"17:60","ar":"وَإِذْ قُلْنَا لَكَ إِنَّ رَبَّكَ أَحَاطَ بِٱلنَّاسِ ۚ وَمَا جَعَلْنَا ٱلرُّءْيَا ٱلَّتِىٓ أَرَيْنَـٰكَ إِلَّا فِتْنَةً لِّلنَّاسِ وَٱلشَّجَرَةَ ٱلْمَلْعُونَةَ فِى ٱلْقُرْءَانِ ۚ وَنُخَوِّفُهُمْ فَمَا يَزِيدُهُمْ إِلَّا طُغْيَـٰنًا كَبِيرًا","en":"And [remember, O Muḥammad], when We told you, \"Indeed, your Lord has encompassed the people.\"1 And We did not make the sight which We showed you2 except as a trial for the people, as was the accursed tree [mentioned] in the Qur’ān. And We threaten [i.e., warn] them, but it increases them not except in great transgression.","tr":"Wa-ith qulna laka inna rabbakaahata binnasi wama jaAAalnaarru/ya allatee araynaka illafitnatan linnasi washshajarataalmalAAoonata fee alqur-ani wanukhawwifuhum famayazeeduhum illa tughyanan kabeera","juz":15,"page":288},{"s":17,"a":61,"key":"17:61","ar":"وَإِذْ قُلْنَا لِلْمَلَـٰٓئِكَةِ ٱسْجُدُوا۟ لِـَٔادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ قَالَ ءَأَسْجُدُ لِمَنْ خَلَقْتَ طِينًا","en":"And [mention] when We said to the angels, \"Prostrate to Adam,\" and they prostrated, except for Iblees.1 He said, \"Should I prostrate to one You created from clay?\"","tr":"Wa-ith qulna lilmala-ikatiosjudoo li-adama fasajadoo illa ibleesa qalaaasjudu liman khalaqta teena","juz":15,"page":288},{"s":17,"a":62,"key":"17:62","ar":"قَالَ أَرَءَيْتَكَ هَـٰذَا ٱلَّذِى كَرَّمْتَ عَلَىَّ لَئِنْ أَخَّرْتَنِ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ لَأَحْتَنِكَنَّ ذُرِّيَّتَهُۥٓ إِلَّا قَلِيلًا","en":"[Iblees] said, \"Do You see this one whom You have honored above me? If You delay me [i.e., my death] until the Day of Resurrection, I will surely destroy1 his descendants, except for a few.\"","tr":"Qala araaytaka hatha allatheekarramta AAalayya la-in akhkhartani ila yawmi alqiyamatilaahtanikanna thurriyyatahu illa qaleela","juz":15,"page":288},{"s":17,"a":63,"key":"17:63","ar":"قَالَ ٱذْهَبْ فَمَن تَبِعَكَ مِنْهُمْ فَإِنَّ جَهَنَّمَ جَزَآؤُكُمْ جَزَآءً مَّوْفُورًا","en":"[Allāh] said, \"Go, for whoever of them follows you, indeed Hell will be the recompense of [all of] you - an ample recompense.","tr":"Qala ithhab faman tabiAAakaminhum fa-inna jahannama jazaokum jazaan mawfoora","juz":15,"page":288},{"s":17,"a":64,"key":"17:64","ar":"وَٱسْتَفْزِزْ مَنِ ٱسْتَطَعْتَ مِنْهُم بِصَوْتِكَ وَأَجْلِبْ عَلَيْهِم بِخَيْلِكَ وَرَجِلِكَ وَشَارِكْهُمْ فِى ٱلْأَمْوَٰلِ وَٱلْأَوْلَـٰدِ وَعِدْهُمْ ۚ وَمَا يَعِدُهُمُ ٱلشَّيْطَـٰنُ إِلَّا غُرُورًا","en":"And incite [to senselessness] whoever you can among them with your voice and assault them with your horses and foot soldiers and become a partner in their wealth and their children and promise them.\" But Satan does not promise them except delusion.","tr":"Wastafziz mani istataAAtaminhum bisawtika waajlib AAalayhim bikhaylika warajlikawasharik-hum fee al-amwali wal-awladiwaAAidhum wama yaAAiduhumu ashshaytanu illaghuroora","juz":15,"page":288},{"s":17,"a":65,"key":"17:65","ar":"إِنَّ عِبَادِى لَيْسَ لَكَ عَلَيْهِمْ سُلْطَـٰنٌ ۚ وَكَفَىٰ بِرَبِّكَ وَكِيلًا","en":"Indeed, over My [believing] servants there is for you no authority. And sufficient is your Lord as Disposer of affairs.1","tr":"Inna AAibadee laysa laka AAalayhimsultanun wakafa birabbika wakeela","juz":15,"page":288},{"s":17,"a":66,"key":"17:66","ar":"رَّبُّكُمُ ٱلَّذِى يُزْجِى لَكُمُ ٱلْفُلْكَ فِى ٱلْبَحْرِ لِتَبْتَغُوا۟ مِن فَضْلِهِۦٓ ۚ إِنَّهُۥ كَانَ بِكُمْ رَحِيمًا","en":"It is your Lord who drives the ship for you through the sea that you may seek of His bounty. Indeed, He is ever, to you, Merciful.","tr":"Rabbukumu allathee yuzjee lakumualfulka fee albahri litabtaghoo min fadlihi innahukana bikum raheema","juz":15,"page":288},{"s":17,"a":67,"key":"17:67","ar":"وَإِذَا مَسَّكُمُ ٱلضُّرُّ فِى ٱلْبَحْرِ ضَلَّ مَن تَدْعُونَ إِلَّآ إِيَّاهُ ۖ فَلَمَّا نَجَّىٰكُمْ إِلَى ٱلْبَرِّ أَعْرَضْتُمْ ۚ وَكَانَ ٱلْإِنسَـٰنُ كَفُورًا","en":"And when adversity touches you at sea, lost are [all] those you invoke except for Him. But when He delivers you to the land, you turn away [from Him]. And ever is man ungrateful.","tr":"Wa-itha massakumu addurrufee albahri dalla man tadAAoona illa iyyahufalamma najjakum ila albarri aAAradtumwakana al-insanu kafoora","juz":15,"page":289},{"s":17,"a":68,"key":"17:68","ar":"أَفَأَمِنتُمْ أَن يَخْسِفَ بِكُمْ جَانِبَ ٱلْبَرِّ أَوْ يُرْسِلَ عَلَيْكُمْ حَاصِبًا ثُمَّ لَا تَجِدُوا۟ لَكُمْ وَكِيلًا","en":"Then do you feel secure that [instead] He will not cause a part of the land to swallow you or send against you a storm of stones? Then you would not find for yourselves an advocate.","tr":"Afaamintum an yakhsifa bikum janibaalbarri aw yursila AAalaykum hasiban thumma latajidoo lakum wakeela","juz":15,"page":289},{"s":17,"a":69,"key":"17:69","ar":"أَمْ أَمِنتُمْ أَن يُعِيدَكُمْ فِيهِ تَارَةً أُخْرَىٰ فَيُرْسِلَ عَلَيْكُمْ قَاصِفًا مِّنَ ٱلرِّيحِ فَيُغْرِقَكُم بِمَا كَفَرْتُمْ ۙ ثُمَّ لَا تَجِدُوا۟ لَكُمْ عَلَيْنَا بِهِۦ تَبِيعًا","en":"Or do you feel secure that He will not send you back into it [i.e., the sea] another time and send upon you a hurricane of wind and drown you for what you denied?1 Then you would not find for yourselves against Us an avenger.2","tr":"Am amintum an yuAAeedakum feehi taratanokhra fayursila AAalaykum qasifan mina arreehifayughriqakum bima kafartum thumma la tajidoo lakumAAalayna bihi tabeeAAa","juz":15,"page":289},{"s":17,"a":70,"key":"17:70","ar":"۞ وَلَقَدْ كَرَّمْنَا بَنِىٓ ءَادَمَ وَحَمَلْنَـٰهُمْ فِى ٱلْبَرِّ وَٱلْبَحْرِ وَرَزَقْنَـٰهُم مِّنَ ٱلطَّيِّبَـٰتِ وَفَضَّلْنَـٰهُمْ عَلَىٰ كَثِيرٍ مِّمَّنْ خَلَقْنَا تَفْضِيلًا","en":"And We have certainly honored the children of Adam and carried them on the land and sea and provided for them of the good things and preferred them over much of what We have created, with [definite] preference.","tr":"Walaqad karramna banee adamawahamalnahum fee albarri walbahriwarazaqnahum mina attayyibati wafaddalnahumAAala katheerin mimman khalaqna tafdeela","juz":15,"page":289},{"s":17,"a":71,"key":"17:71","ar":"يَوْمَ نَدْعُوا۟ كُلَّ أُنَاسٍۭ بِإِمَـٰمِهِمْ ۖ فَمَنْ أُوتِىَ كِتَـٰبَهُۥ بِيَمِينِهِۦ فَأُو۟لَـٰٓئِكَ يَقْرَءُونَ كِتَـٰبَهُمْ وَلَا يُظْلَمُونَ فَتِيلًا","en":"[Mention, O Muḥammad], the Day We will call forth every people with their record [of deeds].1 Then whoever is given his record in his right hand - those will read their records, and injustice will not be done to them, [even] as much as a thread [inside the date seed].","tr":"Yawma nadAAoo kulla onasin bi-imamihimfaman ootiya kitabahu biyameenihi faola-ikayaqraoona kitabahum wala yuthlamoonafateela","juz":15,"page":289},{"s":17,"a":72,"key":"17:72","ar":"وَمَن كَانَ فِى هَـٰذِهِۦٓ أَعْمَىٰ فَهُوَ فِى ٱلْـَٔاخِرَةِ أَعْمَىٰ وَأَضَلُّ سَبِيلًا","en":"And whoever is blind1 in this [life] will be blind in the Hereafter and more astray in way.","tr":"Waman kana fee hathihi aAAmafahuwa fee al-akhirati aAAma waadallu sabeela","juz":15,"page":289},{"s":17,"a":73,"key":"17:73","ar":"وَإِن كَادُوا۟ لَيَفْتِنُونَكَ عَنِ ٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ لِتَفْتَرِىَ عَلَيْنَا غَيْرَهُۥ ۖ وَإِذًا لَّٱتَّخَذُوكَ خَلِيلًا","en":"And indeed, they were about to tempt you away from that which We revealed to you in order to [make] you invent about Us something else; and then they would have taken you as a friend.","tr":"Wa-in kadoo layaftinoonaka AAani allatheeawhayna ilayka litaftariya AAalayna ghayrahuwa-ithan lattakhathooka khaleela","juz":15,"page":289},{"s":17,"a":74,"key":"17:74","ar":"وَلَوْلَآ أَن ثَبَّتْنَـٰكَ لَقَدْ كِدتَّ تَرْكَنُ إِلَيْهِمْ شَيْـًٔا قَلِيلًا","en":"And if We had not strengthened you, you would have almost inclined to them a little.","tr":"Walawla an thabbatnaka laqadkidta tarkanu ilayhim shay-an qaleela","juz":15,"page":289},{"s":17,"a":75,"key":"17:75","ar":"إِذًا لَّأَذَقْنَـٰكَ ضِعْفَ ٱلْحَيَوٰةِ وَضِعْفَ ٱلْمَمَاتِ ثُمَّ لَا تَجِدُ لَكَ عَلَيْنَا نَصِيرًا","en":"Then [if you had], We would have made you taste double [punishment in] life and double [after] death. Then you would not find for yourself against Us a helper.","tr":"Ithan laathaqnaka diAAfaalhayati wadiAAfa almamati thumma latajidu laka AAalayna naseera","juz":15,"page":289},{"s":17,"a":76,"key":"17:76","ar":"وَإِن كَادُوا۟ لَيَسْتَفِزُّونَكَ مِنَ ٱلْأَرْضِ لِيُخْرِجُوكَ مِنْهَا ۖ وَإِذًا لَّا يَلْبَثُونَ خِلَـٰفَكَ إِلَّا قَلِيلًا","en":"And indeed, they were about to provoke [i.e., drive] you from the land [i.e., Makkah] to evict you therefrom. And then [when they do], they will not remain [there] after you, except for a little.1","tr":"Wa-in kadoo layastafizzoonaka minaal-ardi liyukhrijooka minha wa-ithan layalbathoona khilafaka illa qaleela","juz":15,"page":290},{"s":17,"a":77,"key":"17:77","ar":"سُنَّةَ مَن قَدْ أَرْسَلْنَا قَبْلَكَ مِن رُّسُلِنَا ۖ وَلَا تَجِدُ لِسُنَّتِنَا تَحْوِيلًا","en":"[That is Our] established way for those We had sent before you of Our messengers; and you will not find in Our way any alteration.","tr":"Sunnata man qad arsalna qablaka minrusulina wala tajidu lisunnatina tahweela","juz":15,"page":290},{"s":17,"a":78,"key":"17:78","ar":"أَقِمِ ٱلصَّلَوٰةَ لِدُلُوكِ ٱلشَّمْسِ إِلَىٰ غَسَقِ ٱلَّيْلِ وَقُرْءَانَ ٱلْفَجْرِ ۖ إِنَّ قُرْءَانَ ٱلْفَجْرِ كَانَ مَشْهُودًا","en":"Establish prayer at the decline of the sun [from its meridian] until the darkness of the night1 and [also] the Qur’ān [i.e., recitation] of dawn.2 Indeed, the recitation of dawn is ever witnessed.","tr":"Aqimi assalatalidulooki ashshamsi ila ghasaqi allayli waqur-anaalfajri inna qur-ana alfajri kana mashhooda","juz":15,"page":290},{"s":17,"a":79,"key":"17:79","ar":"وَمِنَ ٱلَّيْلِ فَتَهَجَّدْ بِهِۦ نَافِلَةً لَّكَ عَسَىٰٓ أَن يَبْعَثَكَ رَبُّكَ مَقَامًا مَّحْمُودًا","en":"And from [part of] the night, pray1 with it [i.e., recitation of the Qur’ān] as additional [worship] for you; it is expected that2 your Lord will resurrect you to a praised station.3","tr":"Wamina allayli fatahajjad bihi nafilatanlaka AAasa an yabAAathaka rabbuka maqaman mahmooda","juz":15,"page":290},{"s":17,"a":80,"key":"17:80","ar":"وَقُل رَّبِّ أَدْخِلْنِى مُدْخَلَ صِدْقٍ وَأَخْرِجْنِى مُخْرَجَ صِدْقٍ وَٱجْعَل لِّى مِن لَّدُنكَ سُلْطَـٰنًا نَّصِيرًا","en":"And say, \"My Lord, cause me to enter a sound entrance1 and to exit a sound exit2 and grant me from Yourself a supporting authority.\"","tr":"Waqul rabbi adkhilnee mudkhala sidqinwaakhrijnee mukhraja sidqin wajAAal lee minladunka sultanan naseera","juz":15,"page":290},{"s":17,"a":81,"key":"17:81","ar":"وَقُلْ جَآءَ ٱلْحَقُّ وَزَهَقَ ٱلْبَـٰطِلُ ۚ إِنَّ ٱلْبَـٰطِلَ كَانَ زَهُوقًا","en":"And say, \"Truth has come, and falsehood has departed. Indeed is falsehood, [by nature], ever bound to depart.\"","tr":"Waqul jaa alhaqqu wazahaqa albatiluinna albatila kana zahooqa","juz":15,"page":290},{"s":17,"a":82,"key":"17:82","ar":"وَنُنَزِّلُ مِنَ ٱلْقُرْءَانِ مَا هُوَ شِفَآءٌ وَرَحْمَةٌ لِّلْمُؤْمِنِينَ ۙ وَلَا يَزِيدُ ٱلظَّـٰلِمِينَ إِلَّا خَسَارًا","en":"And We send down of the Qur’ān that which is healing and mercy for the believers, but it does not increase the wrongdoers except in loss.","tr":"Wanunazzilu mina alqur-ani mahuwa shifaon warahmatun lilmu/mineena walayazeedu aththalimeena illakhasara","juz":15,"page":290},{"s":17,"a":83,"key":"17:83","ar":"وَإِذَآ أَنْعَمْنَا عَلَى ٱلْإِنسَـٰنِ أَعْرَضَ وَنَـَٔا بِجَانِبِهِۦ ۖ وَإِذَا مَسَّهُ ٱلشَّرُّ كَانَ يَـُٔوسًا","en":"And when We bestow favor upon man [i.e., the disbeliever], he turns away and distances himself; and when evil touches him, he is ever despairing.","tr":"Wa-itha anAAamna AAalaal-insani aAArada wanaa bijanibihiwa-itha massahu ashsharru kana yaoosa","juz":15,"page":290},{"s":17,"a":84,"key":"17:84","ar":"قُلْ كُلٌّ يَعْمَلُ عَلَىٰ شَاكِلَتِهِۦ فَرَبُّكُمْ أَعْلَمُ بِمَنْ هُوَ أَهْدَىٰ سَبِيلًا","en":"Say, \"Each works according to his manner, but your Lord is most knowing of who is best guided in way.\"","tr":"Qul kullun yaAAmalu AAala shakilatihifarabbukum aAAlamu biman huwa ahda sabeela","juz":15,"page":290},{"s":17,"a":85,"key":"17:85","ar":"وَيَسْـَٔلُونَكَ عَنِ ٱلرُّوحِ ۖ قُلِ ٱلرُّوحُ مِنْ أَمْرِ رَبِّى وَمَآ أُوتِيتُم مِّنَ ٱلْعِلْمِ إِلَّا قَلِيلًا","en":"And they ask you, [O Muḥammad], about the soul. Say, \"The soul is of the affair [i.e., concern] of my Lord. And you [i.e., mankind] have not been given of knowledge except a little.\"","tr":"Wayas-aloonaka AAani arroohiquli arroohu min amri rabbee wama ooteetummina alAAilmi illa qaleela","juz":15,"page":290},{"s":17,"a":86,"key":"17:86","ar":"وَلَئِن شِئْنَا لَنَذْهَبَنَّ بِٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ ثُمَّ لَا تَجِدُ لَكَ بِهِۦ عَلَيْنَا وَكِيلًا","en":"And if We willed, We could surely do away with that which We revealed to you. Then you would not find for yourself concerning it an advocate against Us.","tr":"Wala-in shi/na lanathhabannabillathee awhayna ilayka thumma latajidu laka bihi AAalayna wakeela","juz":15,"page":290},{"s":17,"a":87,"key":"17:87","ar":"إِلَّا رَحْمَةً مِّن رَّبِّكَ ۚ إِنَّ فَضْلَهُۥ كَانَ عَلَيْكَ كَبِيرًا","en":"Except [We have left it with you] as a mercy from your Lord. Indeed, His favor upon you has ever been great.","tr":"Illa rahmatan min rabbika innafadlahu kana AAalayka kabeera","juz":15,"page":291},{"s":17,"a":88,"key":"17:88","ar":"قُل لَّئِنِ ٱجْتَمَعَتِ ٱلْإِنسُ وَٱلْجِنُّ عَلَىٰٓ أَن يَأْتُوا۟ بِمِثْلِ هَـٰذَا ٱلْقُرْءَانِ لَا يَأْتُونَ بِمِثْلِهِۦ وَلَوْ كَانَ بَعْضُهُمْ لِبَعْضٍ ظَهِيرًا","en":"Say, \"If mankind and the jinn gathered in order to produce the like of this Qur’ān, they could not produce the like of it, even if they were to each other assistants.\"","tr":"Qul la-ini ijtamaAAati al-insu waljinnuAAala an ya/too bimithli hatha alqur-ani laya/toona bimithlihi walaw kana baAAduhum libaAAdinthaheera","juz":15,"page":291},{"s":17,"a":89,"key":"17:89","ar":"وَلَقَدْ صَرَّفْنَا لِلنَّاسِ فِى هَـٰذَا ٱلْقُرْءَانِ مِن كُلِّ مَثَلٍ فَأَبَىٰٓ أَكْثَرُ ٱلنَّاسِ إِلَّا كُفُورًا","en":"And We have certainly diversified for the people in this Qur’ān from every [kind of] example, but most of the people refused except disbelief.","tr":"Walaqad sarrafna linnasifee hatha alqur-ani min kulli mathalin faabaaktharu annasi illa kufoora","juz":15,"page":291},{"s":17,"a":90,"key":"17:90","ar":"وَقَالُوا۟ لَن نُّؤْمِنَ لَكَ حَتَّىٰ تَفْجُرَ لَنَا مِنَ ٱلْأَرْضِ يَنۢبُوعًا","en":"And they say, \"We will not believe you until you break open for us from the ground a spring","tr":"Waqaloo lan nu/mina laka hattatafjura lana mina al-ardi yanbooAAa","juz":15,"page":291},{"s":17,"a":91,"key":"17:91","ar":"أَوْ تَكُونَ لَكَ جَنَّةٌ مِّن نَّخِيلٍ وَعِنَبٍ فَتُفَجِّرَ ٱلْأَنْهَـٰرَ خِلَـٰلَهَا تَفْجِيرًا","en":"Or [until] you have a garden of palm trees and grapes and make rivers gush forth within them in force [and abundance]","tr":"Aw takoona laka jannatun min nakheelinwaAAinabin fatufajjira al-anhara khilalahatafjeera","juz":15,"page":291},{"s":17,"a":92,"key":"17:92","ar":"أَوْ تُسْقِطَ ٱلسَّمَآءَ كَمَا زَعَمْتَ عَلَيْنَا كِسَفًا أَوْ تَأْتِىَ بِٱللَّهِ وَٱلْمَلَـٰٓئِكَةِ قَبِيلًا","en":"Or you make the heaven fall upon us in fragments as you have claimed or you bring Allāh and the angels before [us]","tr":"Aw tusqita assamaa kamazaAAamta AAalayna kisafan aw ta/tiya billahiwalmala-ikati qabeela","juz":15,"page":291},{"s":17,"a":93,"key":"17:93","ar":"أَوْ يَكُونَ لَكَ بَيْتٌ مِّن زُخْرُفٍ أَوْ تَرْقَىٰ فِى ٱلسَّمَآءِ وَلَن نُّؤْمِنَ لِرُقِيِّكَ حَتَّىٰ تُنَزِّلَ عَلَيْنَا كِتَـٰبًا نَّقْرَؤُهُۥ ۗ قُلْ سُبْحَانَ رَبِّى هَلْ كُنتُ إِلَّا بَشَرًا رَّسُولًا","en":"Or you have a house of ornament [i.e., gold] or you ascend into the sky. And [even then], we will not believe in your ascension until you bring down to us a book we may read.\" Say, \"Exalted is my Lord! Was I ever but a human messenger?\"","tr":"Aw yakoona laka baytun min zukhrufin aw tarqafee assama-i walan nu/mina liruqiyyika hattatunazzila AAalayna kitaban naqraohu qul subhanarabbee hal kuntu illa basharan rasoola","juz":15,"page":291},{"s":17,"a":94,"key":"17:94","ar":"وَمَا مَنَعَ ٱلنَّاسَ أَن يُؤْمِنُوٓا۟ إِذْ جَآءَهُمُ ٱلْهُدَىٰٓ إِلَّآ أَن قَالُوٓا۟ أَبَعَثَ ٱللَّهُ بَشَرًا رَّسُولًا","en":"And what prevented the people from believing when guidance came to them except that they said, \"Has Allāh sent a human messenger?\"","tr":"Wama manaAAa annasa anyu/minoo ith jaahumu alhuda illa an qalooabaAAatha Allahu basharan rasoola","juz":15,"page":291},{"s":17,"a":95,"key":"17:95","ar":"قُل لَّوْ كَانَ فِى ٱلْأَرْضِ مَلَـٰٓئِكَةٌ يَمْشُونَ مُطْمَئِنِّينَ لَنَزَّلْنَا عَلَيْهِم مِّنَ ٱلسَّمَآءِ مَلَكًا رَّسُولًا","en":"Say, \"If there were upon the earth angels walking securely,1 We would have sent down to them from the heaven an angel [as a] messenger.\"","tr":"Qul law kana fee al-ardi mala-ikatunyamshoona mutma-inneena lanazzalna AAalayhim mina assama-imalakan rasoola","juz":15,"page":291},{"s":17,"a":96,"key":"17:96","ar":"قُلْ كَفَىٰ بِٱللَّهِ شَهِيدًۢا بَيْنِى وَبَيْنَكُمْ ۚ إِنَّهُۥ كَانَ بِعِبَادِهِۦ خَبِيرًۢا بَصِيرًا","en":"Say, \"Sufficient is Allāh as Witness between me and you. Indeed He is ever, concerning His servants, Aware and Seeing.\"","tr":"Qul kafa billahishaheedan baynee wabaynakum innahu kana biAAibadihikhabeeran baseera","juz":15,"page":291},{"s":17,"a":97,"key":"17:97","ar":"وَمَن يَهْدِ ٱللَّهُ فَهُوَ ٱلْمُهْتَدِ ۖ وَمَن يُضْلِلْ فَلَن تَجِدَ لَهُمْ أَوْلِيَآءَ مِن دُونِهِۦ ۖ وَنَحْشُرُهُمْ يَوْمَ ٱلْقِيَـٰمَةِ عَلَىٰ وُجُوهِهِمْ عُمْيًا وَبُكْمًا وَصُمًّا ۖ مَّأْوَىٰهُمْ جَهَنَّمُ ۖ كُلَّمَا خَبَتْ زِدْنَـٰهُمْ سَعِيرًا","en":"And whoever Allāh guides - he is the [rightly] guided; and whoever He sends astray1 - you will never find for them protectors besides Him, and We will gather them on the Day of Resurrection [fallen] on their faces - blind, dumb and deaf. Their refuge is Hell; every time it subsides, We increase [for] them blazing fire.","tr":"Waman yahdi Allahu fahuwa almuhtadiwaman yudlil falan tajida lahum awliyaa min doonihiwanahshuruhum yawma alqiyamati AAalawujoohihim AAumyan wabukman wasumman ma/wahumjahannamu kullama khabat zidnahum saAAeera","juz":15,"page":292},{"s":17,"a":98,"key":"17:98","ar":"ذَٰلِكَ جَزَآؤُهُم بِأَنَّهُمْ كَفَرُوا۟ بِـَٔايَـٰتِنَا وَقَالُوٓا۟ أَءِذَا كُنَّا عِظَـٰمًا وَرُفَـٰتًا أَءِنَّا لَمَبْعُوثُونَ خَلْقًا جَدِيدًا","en":"That is their recompense because they disbelieved in Our verses and said, \"When we are bones and crumbled particles, will we [truly] be resurrected [in] a new creation?\"","tr":"Thalika jazaohum bi-annahumkafaroo bi-ayatina waqaloo a-ithakunna AAithaman warufatana-inna lamabAAoothoona khalqan jadeeda","juz":15,"page":292},{"s":17,"a":99,"key":"17:99","ar":"۞ أَوَلَمْ يَرَوْا۟ أَنَّ ٱللَّهَ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ قَادِرٌ عَلَىٰٓ أَن يَخْلُقَ مِثْلَهُمْ وَجَعَلَ لَهُمْ أَجَلًا لَّا رَيْبَ فِيهِ فَأَبَى ٱلظَّـٰلِمُونَ إِلَّا كُفُورًا","en":"Do they not see that Allāh, who created the heavens and earth, is [the one] Able to create the likes of them? And He has appointed for them a term, about which there is no doubt. But the wrongdoers refuse except disbelief.","tr":"Awa lam yaraw anna Allaha allatheekhalaqa assamawati wal-ardaqadirun AAala an yakhluqa mithlahum wajaAAala lahumajalan la rayba feehi faaba aththalimoonailla kufoora","juz":15,"page":292},{"s":17,"a":100,"key":"17:100","ar":"قُل لَّوْ أَنتُمْ تَمْلِكُونَ خَزَآئِنَ رَحْمَةِ رَبِّىٓ إِذًا لَّأَمْسَكْتُمْ خَشْيَةَ ٱلْإِنفَاقِ ۚ وَكَانَ ٱلْإِنسَـٰنُ قَتُورًا","en":"Say [to them], \"If you possessed the depositories of the mercy of my Lord, then you would withhold out of fear of spending.\" And ever has man been stingy.","tr":"Qul law antum tamlikoona khaza-inarahmati rabbee ithan laamsaktum khashyata al-infaqiwakana al-insanu qatoora","juz":15,"page":292},{"s":17,"a":101,"key":"17:101","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَىٰ تِسْعَ ءَايَـٰتٍۭ بَيِّنَـٰتٍ ۖ فَسْـَٔلْ بَنِىٓ إِسْرَٰٓءِيلَ إِذْ جَآءَهُمْ فَقَالَ لَهُۥ فِرْعَوْنُ إِنِّى لَأَظُنُّكَ يَـٰمُوسَىٰ مَسْحُورًا","en":"And We had certainly given Moses nine evident signs, so ask the Children of Israel [about] when he came to them and Pharaoh said to him, \"Indeed I think, O Moses, that you are affected by magic.\"","tr":"Walaqad atayna moosatisAAa ayatin bayyinatin fas-albanee isra-eela ith jaahum faqalalahu firAAawnu innee laathunnuka ya moosamashoora","juz":15,"page":292},{"s":17,"a":102,"key":"17:102","ar":"قَالَ لَقَدْ عَلِمْتَ مَآ أَنزَلَ هَـٰٓؤُلَآءِ إِلَّا رَبُّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ بَصَآئِرَ وَإِنِّى لَأَظُنُّكَ يَـٰفِرْعَوْنُ مَثْبُورًا","en":"[Moses] said, \"You have already known that none has sent down these [signs] except the Lord of the heavens and the earth as evidence, and indeed I think,1 O Pharaoh, that you are destroyed.\"","tr":"Qala laqad AAalimta ma anzalahaola-i illa rabbu assamawatiwal-ardi basa-ira wa-innee laathunnukaya firAAawnu mathboora","juz":15,"page":292},{"s":17,"a":103,"key":"17:103","ar":"فَأَرَادَ أَن يَسْتَفِزَّهُم مِّنَ ٱلْأَرْضِ فَأَغْرَقْنَـٰهُ وَمَن مَّعَهُۥ جَمِيعًا","en":"So he intended to drive them from the land, but We drowned him and those with him all together.","tr":"Faarada an yastafizzahum mina al-ardifaaghraqnahu waman maAAahu jameeAAa","juz":15,"page":292},{"s":17,"a":104,"key":"17:104","ar":"وَقُلْنَا مِنۢ بَعْدِهِۦ لِبَنِىٓ إِسْرَٰٓءِيلَ ٱسْكُنُوا۟ ٱلْأَرْضَ فَإِذَا جَآءَ وَعْدُ ٱلْـَٔاخِرَةِ جِئْنَا بِكُمْ لَفِيفًا","en":"And We said after him [i.e., Pharaoh] to the Children of Israel, \"Dwell in the land, and when there comes the promise [i.e., appointment] of the Hereafter, We will bring you forth in [one] gathering.\"","tr":"Waqulna min baAAdihi libanee isra-eelaoskunoo al-arda fa-itha jaa waAAdu al-akhiratiji/na bikum lafeefa","juz":15,"page":292},{"s":17,"a":105,"key":"17:105","ar":"وَبِٱلْحَقِّ أَنزَلْنَـٰهُ وَبِٱلْحَقِّ نَزَلَ ۗ وَمَآ أَرْسَلْنَـٰكَ إِلَّا مُبَشِّرًا وَنَذِيرًا","en":"And with the truth We have sent it [i.e., the Qur’ān] down, and with the truth it has descended. And We have not sent you, [O Muḥammad], except as a bringer of good tidings and a warner.","tr":"Wabilhaqqi anzalnahuwabilhaqqi nazala wama arsalnaka illamubashshiran wanatheera","juz":15,"page":293},{"s":17,"a":106,"key":"17:106","ar":"وَقُرْءَانًا فَرَقْنَـٰهُ لِتَقْرَأَهُۥ عَلَى ٱلنَّاسِ عَلَىٰ مُكْثٍ وَنَزَّلْنَـٰهُ تَنزِيلًا","en":"And [it is] a Qur’ān which We have separated [by intervals] that you might recite it to the people over a prolonged period. And We have sent it down progressively.","tr":"Waqur-anan faraqnahulitaqraahu AAala annasi AAalamukthin wanazzalnahu tanzeela","juz":15,"page":293},{"s":17,"a":107,"key":"17:107","ar":"قُلْ ءَامِنُوا۟ بِهِۦٓ أَوْ لَا تُؤْمِنُوٓا۟ ۚ إِنَّ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ مِن قَبْلِهِۦٓ إِذَا يُتْلَىٰ عَلَيْهِمْ يَخِرُّونَ لِلْأَذْقَانِ سُجَّدًا","en":"Say, \"Believe in it or do not believe.\" Indeed, those who were given knowledge before it1 - when it is recited to them, they fall upon their faces in prostration,","tr":"Qul aminoo bihi aw latu/minoo inna allatheena ootoo alAAilma min qablihi ithayutla AAalayhim yakhirroona lil-athqanisujjada","juz":15,"page":293},{"s":17,"a":108,"key":"17:108","ar":"وَيَقُولُونَ سُبْحَـٰنَ رَبِّنَآ إِن كَانَ وَعْدُ رَبِّنَا لَمَفْعُولًا","en":"And they say, \"Exalted is our Lord! Indeed, the promise of our Lord has been fulfilled.\"","tr":"Wayaqooloona subhana rabbinain kana waAAdu rabbina lamafAAoola","juz":15,"page":293},{"s":17,"a":109,"key":"17:109","ar":"وَيَخِرُّونَ لِلْأَذْقَانِ يَبْكُونَ وَيَزِيدُهُمْ خُشُوعًا ۩","en":"And they fall upon their faces weeping, and it [i.e., the Qur’ān] increases them in humble submission.","tr":"Wayakhirroona lil-athqaniyabkoona wayazeeduhum khushooAAa","juz":15,"page":293},{"s":17,"a":110,"key":"17:110","ar":"قُلِ ٱدْعُوا۟ ٱللَّهَ أَوِ ٱدْعُوا۟ ٱلرَّحْمَـٰنَ ۖ أَيًّا مَّا تَدْعُوا۟ فَلَهُ ٱلْأَسْمَآءُ ٱلْحُسْنَىٰ ۚ وَلَا تَجْهَرْ بِصَلَاتِكَ وَلَا تُخَافِتْ بِهَا وَٱبْتَغِ بَيْنَ ذَٰلِكَ سَبِيلًا","en":"Say, \"Call upon Allāh or call upon the Most Merciful [ar-Raḥmān]. Whichever [name] you call - to Him belong the best names.\" And do not recite [too] loudly in your prayer or [too] quietly but seek between that an [intermediate] way.","tr":"Quli odAAoo Allaha awi odAAoo arrahmanaayyan ma tadAAoo falahu al-asmao alhusnawala tajhar bisalatika wala tukhafitbiha wabtaghi bayna thalika sabeela","juz":15,"page":293},{"s":17,"a":111,"key":"17:111","ar":"وَقُلِ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى لَمْ يَتَّخِذْ وَلَدًا وَلَمْ يَكُن لَّهُۥ شَرِيكٌ فِى ٱلْمُلْكِ وَلَمْ يَكُن لَّهُۥ وَلِىٌّ مِّنَ ٱلذُّلِّ ۖ وَكَبِّرْهُ تَكْبِيرًۢا","en":"And say, \"Praise to Allāh, who has not taken a son and has had no partner in [His] dominion and has no [need of a] protector out of weakness; and glorify Him with [great] glorification.\"","tr":"Waquli alhamdu lillahi allatheelam yattakhith waladan walam yakun lahu shareekun feealmulki walam yakun lahu waliyyun mina aththulliwakabbirhu takbeera","juz":15,"page":293},{"s":18,"a":1,"key":"18:1","ar":" ٱلْحَمْدُ لِلَّهِ ٱلَّذِىٓ أَنزَلَ عَلَىٰ عَبْدِهِ ٱلْكِتَـٰبَ وَلَمْ يَجْعَل لَّهُۥ عِوَجَا ۜ","en":"[All] praise is [due] to Allāh, who has sent down upon His Servant [Muḥammad (ﷺ)] the Book and has not made therein any deviance.1","tr":"Alhamdu lillahi allatheeanzala AAala AAabdihi alkitaba walam yajAAal lahuAAiwaja","juz":15,"page":293},{"s":18,"a":2,"key":"18:2","ar":"قَيِّمًا لِّيُنذِرَ بَأْسًا شَدِيدًا مِّن لَّدُنْهُ وَيُبَشِّرَ ٱلْمُؤْمِنِينَ ٱلَّذِينَ يَعْمَلُونَ ٱلصَّـٰلِحَـٰتِ أَنَّ لَهُمْ أَجْرًا حَسَنًا","en":"[He has made it] straight, to warn of severe punishment from Him and to give good tidings to the believers who do righteous deeds that they will have a good reward [i.e., Paradise].","tr":"Qayyiman liyunthira ba/san shadeedanmin ladunhu wayubashshira almu/mineena allatheenayaAAmaloona assalihati anna lahum ajran hasana","juz":15,"page":293},{"s":18,"a":3,"key":"18:3","ar":"مَّـٰكِثِينَ فِيهِ أَبَدًا","en":"In which they will remain forever","tr":"Makitheena feehi abada","juz":15,"page":293},{"s":18,"a":4,"key":"18:4","ar":"وَيُنذِرَ ٱلَّذِينَ قَالُوا۟ ٱتَّخَذَ ٱللَّهُ وَلَدًا","en":"And to warn those who say, \"Allāh has taken a son\".","tr":"Wayunthira allatheena qalooittakhatha Allahu walada","juz":15,"page":293},{"s":18,"a":5,"key":"18:5","ar":"مَّا لَهُم بِهِۦ مِنْ عِلْمٍ وَلَا لِـَٔابَآئِهِمْ ۚ كَبُرَتْ كَلِمَةً تَخْرُجُ مِنْ أَفْوَٰهِهِمْ ۚ إِن يَقُولُونَ إِلَّا كَذِبًا","en":"They have no knowledge of it,1 nor had their fathers. Grave is the word that comes out of their mouths; they speak not except a lie.","tr":"Ma lahum bihi min AAilmin walali-aba-ihim kaburat kalimatan takhruju min afwahihimin yaqooloona illa kathiba","juz":15,"page":294},{"s":18,"a":6,"key":"18:6","ar":"فَلَعَلَّكَ بَـٰخِعٌ نَّفْسَكَ عَلَىٰٓ ءَاثَـٰرِهِمْ إِن لَّمْ يُؤْمِنُوا۟ بِهَـٰذَا ٱلْحَدِيثِ أَسَفًا","en":"Then perhaps you would kill yourself through grief over them, [O Muḥammad], if they do not believe in this message, [and] out of sorrow.","tr":"FalaAAallaka bakhiAAun nafsaka AAalaatharihim in lam yu/minoo bihatha alhadeethiasafa","juz":15,"page":294},{"s":18,"a":7,"key":"18:7","ar":"إِنَّا جَعَلْنَا مَا عَلَى ٱلْأَرْضِ زِينَةً لَّهَا لِنَبْلُوَهُمْ أَيُّهُمْ أَحْسَنُ عَمَلًا","en":"Indeed, We have made that which is on the earth adornment for it that We may test them [as to] which of them is best in deed.","tr":"Inna jaAAalna ma AAalaal-ardi zeenatan laha linabluwahum ayyuhum ahsanuAAamala","juz":15,"page":294},{"s":18,"a":8,"key":"18:8","ar":"وَإِنَّا لَجَـٰعِلُونَ مَا عَلَيْهَا صَعِيدًا جُرُزًا","en":"And indeed, We will make that which is upon it [into] a barren ground.","tr":"Wa-inna lajaAAiloona maAAalayha saAAeedan juruza","juz":15,"page":294},{"s":18,"a":9,"key":"18:9","ar":"أَمْ حَسِبْتَ أَنَّ أَصْحَـٰبَ ٱلْكَهْفِ وَٱلرَّقِيمِ كَانُوا۟ مِنْ ءَايَـٰتِنَا عَجَبًا","en":"Or have you thought that the companions of the cave and the inscription were, among Our signs, a wonder?1","tr":"Am hasibta anna as-habaalkahfi warraqeemi kanoo min ayatinaAAajaba","juz":15,"page":294},{"s":18,"a":10,"key":"18:10","ar":"إِذْ أَوَى ٱلْفِتْيَةُ إِلَى ٱلْكَهْفِ فَقَالُوا۟ رَبَّنَآ ءَاتِنَا مِن لَّدُنكَ رَحْمَةً وَهَيِّئْ لَنَا مِنْ أَمْرِنَا رَشَدًا","en":"[Mention] when the youths retreated to the cave and said, \"Our Lord, grant us from Yourself mercy and prepare for us from our affair right guidance.\"","tr":"Ith awa alfityatu ilaalkahfi faqaloo rabbana atina minladunka rahmatan wahayyi/ lana min amrinarashada","juz":15,"page":294},{"s":18,"a":11,"key":"18:11","ar":"فَضَرَبْنَا عَلَىٰٓ ءَاذَانِهِمْ فِى ٱلْكَهْفِ سِنِينَ عَدَدًا","en":"So We cast [a cover of sleep] over their ears within the cave for a number of years.","tr":"Fadarabna AAala athanihimfee alkahfi sineena AAadada","juz":15,"page":294},{"s":18,"a":12,"key":"18:12","ar":"ثُمَّ بَعَثْنَـٰهُمْ لِنَعْلَمَ أَىُّ ٱلْحِزْبَيْنِ أَحْصَىٰ لِمَا لَبِثُوٓا۟ أَمَدًا","en":"Then We awakened them that We might show which of the two factions was most precise in calculating what [extent] they had remained in time.","tr":"Thumma baAAathnahum linaAAlama ayyualhizbayni ahsa lima labithoo amada","juz":15,"page":294},{"s":18,"a":13,"key":"18:13","ar":"نَّحْنُ نَقُصُّ عَلَيْكَ نَبَأَهُم بِٱلْحَقِّ ۚ إِنَّهُمْ فِتْيَةٌ ءَامَنُوا۟ بِرَبِّهِمْ وَزِدْنَـٰهُمْ هُدًى","en":"It is We who relate to you, [O Muḥammad], their story in truth. Indeed, they were youths who believed in their Lord, and We increased them in guidance.","tr":"Nahnu naqussu AAalaykanabaahum bilhaqqi innahum fityatun amanoobirabbihim wazidnahum huda","juz":15,"page":294},{"s":18,"a":14,"key":"18:14","ar":"وَرَبَطْنَا عَلَىٰ قُلُوبِهِمْ إِذْ قَامُوا۟ فَقَالُوا۟ رَبُّنَا رَبُّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ لَن نَّدْعُوَا۟ مِن دُونِهِۦٓ إِلَـٰهًا ۖ لَّقَدْ قُلْنَآ إِذًا شَطَطًا","en":"And We bound [i.e., made firm] their hearts when they stood up and said, \"Our Lord is the Lord of the heavens and the earth. Never will we invoke besides Him any deity. We would have certainly spoken, then, an excessive transgression.","tr":"Warabatna AAalaquloobihim ith qamoo faqaloo rabbunarabbu assamawati wal-ardilan nadAAuwa min doonihi ilahan laqad qulna ithanshatata","juz":15,"page":294},{"s":18,"a":15,"key":"18:15","ar":"هَـٰٓؤُلَآءِ قَوْمُنَا ٱتَّخَذُوا۟ مِن دُونِهِۦٓ ءَالِهَةً ۖ لَّوْلَا يَأْتُونَ عَلَيْهِم بِسُلْطَـٰنٍۭ بَيِّنٍ ۖ فَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا","en":"These, our people, have taken besides Him deities. Why do they not bring for [worship of] them a clear evidence? And who is more unjust than one who invents about Allāh a lie?\"","tr":"Haola-i qawmuna ittakhathoomin doonihi alihatan lawla ya/toona AAalayhim bisultaninbayyinin faman athlamu mimmani iftara AAalaAllahi kathiba","juz":15,"page":294},{"s":18,"a":16,"key":"18:16","ar":"وَإِذِ ٱعْتَزَلْتُمُوهُمْ وَمَا يَعْبُدُونَ إِلَّا ٱللَّهَ فَأْوُۥٓا۟ إِلَى ٱلْكَهْفِ يَنشُرْ لَكُمْ رَبُّكُم مِّن رَّحْمَتِهِۦ وَيُهَيِّئْ لَكُم مِّنْ أَمْرِكُم مِّرْفَقًا","en":"[The youths said to one another], \"And when you have withdrawn from them and that which they worship other than Allāh, retreat to the cave. Your Lord will spread out for you of His mercy and will prepare for you from your affair facility.\"","tr":"Wa-ithi iAAtazaltumoohum wamayaAAbudoona illa Allaha fa/woo ila alkahfiyanshur lakum rabbukum min rahmatihi wayuhayyi/ lakum minamrikum mirfaqa","juz":15,"page":295},{"s":18,"a":17,"key":"18:17","ar":"۞ وَتَرَى ٱلشَّمْسَ إِذَا طَلَعَت تَّزَٰوَرُ عَن كَهْفِهِمْ ذَاتَ ٱلْيَمِينِ وَإِذَا غَرَبَت تَّقْرِضُهُمْ ذَاتَ ٱلشِّمَالِ وَهُمْ فِى فَجْوَةٍ مِّنْهُ ۚ ذَٰلِكَ مِنْ ءَايَـٰتِ ٱللَّهِ ۗ مَن يَهْدِ ٱللَّهُ فَهُوَ ٱلْمُهْتَدِ ۖ وَمَن يُضْلِلْ فَلَن تَجِدَ لَهُۥ وَلِيًّا مُّرْشِدًا","en":"And [had you been present], you would see the sun when it rose, inclining away from their cave on the right, and when it set, passing away from them on the left, while they were [lying] within an open space thereof. That was from the signs of Allāh. He whom Allāh guides is the [rightly] guided, but he whom He sends astray - never will you find for him a protecting guide.","tr":"Watara ashshamsa itha talaAAattazawaru AAan kahfihim thata alyameeni wa-ithagharabat taqriduhum thata ashshimaliwahum fee fajwatin minhu thalika min ayatiAllahi man yahdi Allahu fahuwa almuhtadi waman yudlilfalan tajida lahu waliyyan murshida","juz":15,"page":295},{"s":18,"a":18,"key":"18:18","ar":"وَتَحْسَبُهُمْ أَيْقَاظًا وَهُمْ رُقُودٌ ۚ وَنُقَلِّبُهُمْ ذَاتَ ٱلْيَمِينِ وَذَاتَ ٱلشِّمَالِ ۖ وَكَلْبُهُم بَـٰسِطٌ ذِرَاعَيْهِ بِٱلْوَصِيدِ ۚ لَوِ ٱطَّلَعْتَ عَلَيْهِمْ لَوَلَّيْتَ مِنْهُمْ فِرَارًا وَلَمُلِئْتَ مِنْهُمْ رُعْبًا","en":"And you would think them awake, while they were asleep. And We turned them to the right and to the left, while their dog stretched his forelegs at the entrance. If you had looked at them, you would have turned from them in flight and been filled by them with terror.","tr":"Watahsabuhum ayqathanwahum ruqoodun wanuqallibuhum thata alyameeni wathataashshimali wakalbuhum basitun thiraAAayhibilwaseedi lawi ittalaAAta AAalayhimlawallayta minhum firaran walamuli/ta minhum ruAAba","juz":15,"page":295},{"s":18,"a":19,"key":"18:19","ar":"وَكَذَٰلِكَ بَعَثْنَـٰهُمْ لِيَتَسَآءَلُوا۟ بَيْنَهُمْ ۚ قَالَ قَآئِلٌ مِّنْهُمْ كَمْ لَبِثْتُمْ ۖ قَالُوا۟ لَبِثْنَا يَوْمًا أَوْ بَعْضَ يَوْمٍ ۚ قَالُوا۟ رَبُّكُمْ أَعْلَمُ بِمَا لَبِثْتُمْ فَٱبْعَثُوٓا۟ أَحَدَكُم بِوَرِقِكُمْ هَـٰذِهِۦٓ إِلَى ٱلْمَدِينَةِ فَلْيَنظُرْ أَيُّهَآ أَزْكَىٰ طَعَامًا فَلْيَأْتِكُم بِرِزْقٍ مِّنْهُ وَلْيَتَلَطَّفْ وَلَا يُشْعِرَنَّ بِكُمْ أَحَدًا","en":"And similarly,1 We awakened them that they might question one another. Said a speaker from among them, \"How long have you remained [here]?\" They said, \"We have remained a day or part of a day.\" They said, \"Your Lord is most knowing of how long you remained. So send one of you with this silver coin of yours to the city and let him look to which is the best of food and bring you provision from it and let him be cautious. And let no one be aware of you.","tr":"Wakathalika baAAathnahumliyatasaaloo baynahum qala qa-ilun minhumkam labithtum qaloo labithna yawman aw baAAdayawmin qaloo rabbukum aAAlamu bima labithtum fabAAathooahadakum biwariqikum hathihi ila almadeenatifalyanthur ayyuha azka taAAamanfalya/tikum birizqin minhu walyatalattaf walayushAAiranna bikum ahada","juz":15,"page":295},{"s":18,"a":20,"key":"18:20","ar":"إِنَّهُمْ إِن يَظْهَرُوا۟ عَلَيْكُمْ يَرْجُمُوكُمْ أَوْ يُعِيدُوكُمْ فِى مِلَّتِهِمْ وَلَن تُفْلِحُوٓا۟ إِذًا أَبَدًا","en":"Indeed, if they come to know of you, they will stone you or return you to their religion. And never would you succeed, then - ever.\"","tr":"Innahum in yathharoo AAalaykumyarjumookum aw yuAAeedookum fee millatihim walan tuflihooithan abada","juz":15,"page":295},{"s":18,"a":21,"key":"18:21","ar":"وَكَذَٰلِكَ أَعْثَرْنَا عَلَيْهِمْ لِيَعْلَمُوٓا۟ أَنَّ وَعْدَ ٱللَّهِ حَقٌّ وَأَنَّ ٱلسَّاعَةَ لَا رَيْبَ فِيهَآ إِذْ يَتَنَـٰزَعُونَ بَيْنَهُمْ أَمْرَهُمْ ۖ فَقَالُوا۟ ٱبْنُوا۟ عَلَيْهِم بُنْيَـٰنًا ۖ رَّبُّهُمْ أَعْلَمُ بِهِمْ ۚ قَالَ ٱلَّذِينَ غَلَبُوا۟ عَلَىٰٓ أَمْرِهِمْ لَنَتَّخِذَنَّ عَلَيْهِم مَّسْجِدًا","en":"And similarly, We caused them to be found that they [who found them] would know that the promise of Allāh is truth and that of the Hour there is no doubt. [That was] when they1 disputed among themselves about their affair and [then] said, \"Construct over them a structure. Their Lord is most knowing about them.\" Said those who prevailed in the matter, \"We will surely take [for ourselves] over them a masjid.\"2","tr":"Wakathalika aAAtharnaAAalayhim liyaAAlamoo anna waAAda Allahi haqqunwaanna asaAAata la rayba feeha ithyatanazaAAoona baynahum amrahum faqaloo ibnooAAalayhim bunyanan rabbuhum aAAlamu bihim qala allatheenaghalaboo AAala amrihim lanattakhithanna AAalayhimmasjida","juz":15,"page":296},{"s":18,"a":22,"key":"18:22","ar":"سَيَقُولُونَ ثَلَـٰثَةٌ رَّابِعُهُمْ كَلْبُهُمْ وَيَقُولُونَ خَمْسَةٌ سَادِسُهُمْ كَلْبُهُمْ رَجْمًۢا بِٱلْغَيْبِ ۖ وَيَقُولُونَ سَبْعَةٌ وَثَامِنُهُمْ كَلْبُهُمْ ۚ قُل رَّبِّىٓ أَعْلَمُ بِعِدَّتِهِم مَّا يَعْلَمُهُمْ إِلَّا قَلِيلٌ ۗ فَلَا تُمَارِ فِيهِمْ إِلَّا مِرَآءً ظَـٰهِرًا وَلَا تَسْتَفْتِ فِيهِم مِّنْهُمْ أَحَدًا","en":"They [i.e., people] will say there were three, the fourth of them being their dog; and they will say there were five, the sixth of them being their dog - guessing at the unseen; and they will say there were seven, and the eighth of them was their dog. Say, [O Muḥammad], \"My Lord is most knowing of their number. None knows them except a few. So do not argue about them except with an obvious argument1 and do not inquire about them among [the speculators] from anyone.\"","tr":"Sayaqooloona thalathatun rabiAAuhumkalbuhum wayaqooloona khamsatun sadisuhum kalbuhum rajmanbilghaybi wayaqooloona sabAAatun wathaminuhumkalbuhum qul rabbee aAAlamu biAAiddatihim ma yaAAlamuhumilla qaleelun fala tumari feehim illamiraan thahiran wala tastaftifeehim minhum ahada","juz":15,"page":296},{"s":18,"a":23,"key":"18:23","ar":"وَلَا تَقُولَنَّ لِشَا۟ىْءٍ إِنِّى فَاعِلٌ ذَٰلِكَ غَدًا","en":"And never say of anything, \"Indeed, I will do that tomorrow,\"","tr":"Wala taqoolanna lishay-in innee faAAilunthalika ghada","juz":15,"page":296},{"s":18,"a":24,"key":"18:24","ar":"إِلَّآ أَن يَشَآءَ ٱللَّهُ ۚ وَٱذْكُر رَّبَّكَ إِذَا نَسِيتَ وَقُلْ عَسَىٰٓ أَن يَهْدِيَنِ رَبِّى لِأَقْرَبَ مِنْ هَـٰذَا رَشَدًا","en":"Except [when adding], \"If Allāh wills.\" And remember your Lord when you forget [it] and say, \"Perhaps my Lord will guide me to what is nearer than this to right conduct.\"","tr":"Illa an yashaa Allahuwathkur rabbaka itha naseeta waqul AAasaan yahdiyani rabbee li-aqraba min hatha rashada","juz":15,"page":296},{"s":18,"a":25,"key":"18:25","ar":"وَلَبِثُوا۟ فِى كَهْفِهِمْ ثَلَـٰثَ مِا۟ئَةٍ سِنِينَ وَٱزْدَادُوا۟ تِسْعًا","en":"And they remained in their cave for three hundred years and exceeded by nine.1","tr":"Walabithoo fee kahfihim thalathami-atin sineena wazdadoo tisAAa","juz":15,"page":296},{"s":18,"a":26,"key":"18:26","ar":"قُلِ ٱللَّهُ أَعْلَمُ بِمَا لَبِثُوا۟ ۖ لَهُۥ غَيْبُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ أَبْصِرْ بِهِۦ وَأَسْمِعْ ۚ مَا لَهُم مِّن دُونِهِۦ مِن وَلِىٍّ وَلَا يُشْرِكُ فِى حُكْمِهِۦٓ أَحَدًا","en":"Say, \"Allāh is most knowing of how long they remained. He has [knowledge of] the unseen [aspects] of the heavens and the earth. How Seeing is He and how Hearing! They have not besides Him any protector, and He shares not His legislation with anyone.\"","tr":"Quli Allahu aAAlamu bimalabithoo lahu ghaybu assamawati wal-ardiabsir bihi waasmiAA ma lahum min doonihi minwaliyyin wala yushriku fee hukmihi ahada","juz":15,"page":296},{"s":18,"a":27,"key":"18:27","ar":"وَٱتْلُ مَآ أُوحِىَ إِلَيْكَ مِن كِتَابِ رَبِّكَ ۖ لَا مُبَدِّلَ لِكَلِمَـٰتِهِۦ وَلَن تَجِدَ مِن دُونِهِۦ مُلْتَحَدًا","en":"And recite, [O Muḥammad], what has been revealed to you of the Book of your Lord. There is no changer of His words, and never will you find in other than Him a refuge.","tr":"Watlu ma oohiya ilaykamin kitabi rabbika la mubaddila likalimatihiwalan tajida min doonihi multahada","juz":15,"page":296},{"s":18,"a":28,"key":"18:28","ar":"وَٱصْبِرْ نَفْسَكَ مَعَ ٱلَّذِينَ يَدْعُونَ رَبَّهُم بِٱلْغَدَوٰةِ وَٱلْعَشِىِّ يُرِيدُونَ وَجْهَهُۥ ۖ وَلَا تَعْدُ عَيْنَاكَ عَنْهُمْ تُرِيدُ زِينَةَ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَلَا تُطِعْ مَنْ أَغْفَلْنَا قَلْبَهُۥ عَن ذِكْرِنَا وَٱتَّبَعَ هَوَىٰهُ وَكَانَ أَمْرُهُۥ فُرُطًا","en":"And keep yourself patient [by being] with those who call upon their Lord in the morning and the evening, seeking His face [i.e., acceptance]. And let not your eyes pass beyond them, desiring adornments of the worldly life, and do not obey one whose heart We have made heedless of Our remembrance and who follows his desire and whose affair is ever [in] neglect.1","tr":"Wasbir nafsaka maAAa allatheenayadAAoona rabbahum bilghadati walAAashiyyiyureedoona wajhahu wala taAAdu AAaynaka AAanhumtureedu zeenata alhayati addunya walatutiAA man aghfalna qalbahu AAan thikrinawattabaAAa hawahu wakana amruhu furuta","juz":15,"page":297},{"s":18,"a":29,"key":"18:29","ar":"وَقُلِ ٱلْحَقُّ مِن رَّبِّكُمْ ۖ فَمَن شَآءَ فَلْيُؤْمِن وَمَن شَآءَ فَلْيَكْفُرْ ۚ إِنَّآ أَعْتَدْنَا لِلظَّـٰلِمِينَ نَارًا أَحَاطَ بِهِمْ سُرَادِقُهَا ۚ وَإِن يَسْتَغِيثُوا۟ يُغَاثُوا۟ بِمَآءٍ كَٱلْمُهْلِ يَشْوِى ٱلْوُجُوهَ ۚ بِئْسَ ٱلشَّرَابُ وَسَآءَتْ مُرْتَفَقًا","en":"And say, \"The truth is from your Lord, so whoever wills - let him believe; and whoever wills - let him disbelieve.\" Indeed, We have prepared for the wrongdoers a fire whose walls will surround them. And if they call for relief, they will be relieved with water like murky oil, which scalds [their] faces. Wretched is the drink, and evil is the resting place.","tr":"Waquli alhaqqu min rabbikum faman shaafalyu/min waman shaa falyakfur inna aAAtadnaliththalimeena naran ahatabihim suradiquha wa-in yastagheethoo yughathoobima-in kalmuhli yashwee alwujooha bi/sa ashsharabuwasaat murtafaqa","juz":15,"page":297},{"s":18,"a":30,"key":"18:30","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ إِنَّا لَا نُضِيعُ أَجْرَ مَنْ أَحْسَنَ عَمَلًا","en":"Indeed, those who have believed and done righteous deeds - indeed, We will not allow to be lost the reward of any who did well in deeds.","tr":"Inna allatheena amanoowaAAamiloo assalihati inna lanudeeAAu ajra man ahsana AAamala","juz":15,"page":297},{"s":18,"a":31,"key":"18:31","ar":"أُو۟لَـٰٓئِكَ لَهُمْ جَنَّـٰتُ عَدْنٍ تَجْرِى مِن تَحْتِهِمُ ٱلْأَنْهَـٰرُ يُحَلَّوْنَ فِيهَا مِنْ أَسَاوِرَ مِن ذَهَبٍ وَيَلْبَسُونَ ثِيَابًا خُضْرًا مِّن سُندُسٍ وَإِسْتَبْرَقٍ مُّتَّكِـِٔينَ فِيهَا عَلَى ٱلْأَرَآئِكِ ۚ نِعْمَ ٱلثَّوَابُ وَحَسُنَتْ مُرْتَفَقًا","en":"Those will have gardens of perpetual residence; beneath them rivers will flow. They will be adorned therein with bracelets of gold and will wear green garments of fine silk and brocade, reclining therein on adorned couches. Excellent is the reward, and good is the resting place.","tr":"Ola-ika lahum jannatu AAadnintajree min tahtihimu al-anharu yuhallawnafeeha min asawira min thahabin waylbasoonathiyaban khudran min sundusin wa-istabraqinmuttaki-eena feeha AAala al-ara-iki niAAma aththawabuwahasunat murtafaqa","juz":15,"page":297},{"s":18,"a":32,"key":"18:32","ar":"۞ وَٱضْرِبْ لَهُم مَّثَلًا رَّجُلَيْنِ جَعَلْنَا لِأَحَدِهِمَا جَنَّتَيْنِ مِنْ أَعْنَـٰبٍ وَحَفَفْنَـٰهُمَا بِنَخْلٍ وَجَعَلْنَا بَيْنَهُمَا زَرْعًا","en":"And present to them an example of two men: We granted to one of them two gardens of grapevines, and We bordered them with palm trees and placed between them [fields of] crops.","tr":"Wadrib lahum mathalanrajulayni jaAAalna li-ahadihima jannataynimin aAAnabin wahafafnahuma binakhlinwajaAAalna baynahuma zarAAa","juz":15,"page":297},{"s":18,"a":33,"key":"18:33","ar":"كِلْتَا ٱلْجَنَّتَيْنِ ءَاتَتْ أُكُلَهَا وَلَمْ تَظْلِم مِّنْهُ شَيْـًٔا ۚ وَفَجَّرْنَا خِلَـٰلَهُمَا نَهَرًا","en":"Each of the two gardens produced its fruit and did not fall short thereof in anything. And We caused to gush forth within them a river.","tr":"Kilta aljannatayni atat okulahawalam tathlim minhu shay-an wafajjarna khilalahumanahara","juz":15,"page":297},{"s":18,"a":34,"key":"18:34","ar":"وَكَانَ لَهُۥ ثَمَرٌ فَقَالَ لِصَـٰحِبِهِۦ وَهُوَ يُحَاوِرُهُۥٓ أَنَا۠ أَكْثَرُ مِنكَ مَالًا وَأَعَزُّ نَفَرًا","en":"And he had fruit, so he said to his companion while he was conversing with him, \"I am greater than you in wealth and mightier in [numbers of] men.\"","tr":"Wakana lahu thamarun faqala lisahibihiwahuwa yuhawiruhu ana aktharu minka malanwaaAAazzu nafara","juz":15,"page":297},{"s":18,"a":35,"key":"18:35","ar":"وَدَخَلَ جَنَّتَهُۥ وَهُوَ ظَالِمٌ لِّنَفْسِهِۦ قَالَ مَآ أَظُنُّ أَن تَبِيدَ هَـٰذِهِۦٓ أَبَدًا","en":"And he entered his garden while he was unjust to himself.1 He said, \"I do not think that this will perish - ever.","tr":"Wadakhala jannatahu wahuwa thalimunlinafsihi qala ma athunnu an tabeedahathihi abada","juz":15,"page":298},{"s":18,"a":36,"key":"18:36","ar":"وَمَآ أَظُنُّ ٱلسَّاعَةَ قَآئِمَةً وَلَئِن رُّدِدتُّ إِلَىٰ رَبِّى لَأَجِدَنَّ خَيْرًا مِّنْهَا مُنقَلَبًا","en":"And I do not think the Hour will occur. And even if I should be brought back to my Lord, I will surely find better than this as a return.\"","tr":"Wama athunnu assaAAataqa-imatan wala-in rudidtu ila rabbee laajidannakhayran minha munqalaba","juz":15,"page":298},{"s":18,"a":37,"key":"18:37","ar":"قَالَ لَهُۥ صَاحِبُهُۥ وَهُوَ يُحَاوِرُهُۥٓ أَكَفَرْتَ بِٱلَّذِى خَلَقَكَ مِن تُرَابٍ ثُمَّ مِن نُّطْفَةٍ ثُمَّ سَوَّىٰكَ رَجُلًا","en":"His companion said to him while he was conversing with him, \"Have you disbelieved in He who created you from dust and then from a sperm-drop and then proportioned you [as] a man?","tr":"Qala lahu sahibuhu wahuwa yuhawiruhuakafarta billathee khalaqaka min turabinthumma min nutfatin thumma sawwaka rajula","juz":15,"page":298},{"s":18,"a":38,"key":"18:38","ar":"لَّـٰكِنَّا۠ هُوَ ٱللَّهُ رَبِّى وَلَآ أُشْرِكُ بِرَبِّىٓ أَحَدًا","en":"But as for me, He is Allāh, my Lord, and I do not associate with my Lord anyone.","tr":"Lakinna huwa Allahu rabbee walaoshriku birabbee ahada","juz":15,"page":298},{"s":18,"a":39,"key":"18:39","ar":"وَلَوْلَآ إِذْ دَخَلْتَ جَنَّتَكَ قُلْتَ مَا شَآءَ ٱللَّهُ لَا قُوَّةَ إِلَّا بِٱللَّهِ ۚ إِن تَرَنِ أَنَا۠ أَقَلَّ مِنكَ مَالًا وَوَلَدًا","en":"And why did you, when you entered your garden, not say, 'What Allāh willed [has occurred]; there is no power except in Allāh'? Although you see me less than you in wealth and children,","tr":"Walawla ith dakhalta jannatakaqulta ma shaa Allahu la quwwata illabillahi in tarani ana aqalla minka malanwawalada","juz":15,"page":298},{"s":18,"a":40,"key":"18:40","ar":"فَعَسَىٰ رَبِّىٓ أَن يُؤْتِيَنِ خَيْرًا مِّن جَنَّتِكَ وَيُرْسِلَ عَلَيْهَا حُسْبَانًا مِّنَ ٱلسَّمَآءِ فَتُصْبِحَ صَعِيدًا زَلَقًا","en":"It may be that my Lord will give me [something] better than your garden and will send upon it a [disastrous] penalty from the sky, and it will become a smooth, dusty ground,","tr":"FaAAasa rabbee an yu/tiyani khayranmin jannatika wayursila AAalayha husbananmina assama-i fatusbiha saAAeedanzalaqa","juz":15,"page":298},{"s":18,"a":41,"key":"18:41","ar":"أَوْ يُصْبِحَ مَآؤُهَا غَوْرًا فَلَن تَسْتَطِيعَ لَهُۥ طَلَبًا","en":"Or its water will become sunken [into the earth], so you would never be able to seek it.\"","tr":"Aw yusbiha maohaghawran falan tastateeAAa lahu talaba","juz":15,"page":298},{"s":18,"a":42,"key":"18:42","ar":"وَأُحِيطَ بِثَمَرِهِۦ فَأَصْبَحَ يُقَلِّبُ كَفَّيْهِ عَلَىٰ مَآ أَنفَقَ فِيهَا وَهِىَ خَاوِيَةٌ عَلَىٰ عُرُوشِهَا وَيَقُولُ يَـٰلَيْتَنِى لَمْ أُشْرِكْ بِرَبِّىٓ أَحَدًا","en":"And his fruits were encompassed [by ruin], so he began to turn his hands about [in dismay] over what he had spent on it, while it had collapsed upon its trellises, and said, \"Oh, I wish I had not associated with my Lord anyone.\"1","tr":"Waoheeta bithamarihi faasbahayuqallibu kaffayhi AAala ma anfaqa feehawahiya khawiyatun AAala AAurooshihawayaqoolu ya laytanee lam oshrik birabbee ahada","juz":15,"page":298},{"s":18,"a":43,"key":"18:43","ar":"وَلَمْ تَكُن لَّهُۥ فِئَةٌ يَنصُرُونَهُۥ مِن دُونِ ٱللَّهِ وَمَا كَانَ مُنتَصِرًا","en":"And there was for him no company to aid him other than Allāh, nor could he defend himself.","tr":"Walam takun lahu fi-atun yansuroonahumin dooni Allahi wama kana muntasira","juz":15,"page":298},{"s":18,"a":44,"key":"18:44","ar":"هُنَالِكَ ٱلْوَلَـٰيَةُ لِلَّهِ ٱلْحَقِّ ۚ هُوَ خَيْرٌ ثَوَابًا وَخَيْرٌ عُقْبًا","en":"There1 the authority is [completely] for Allāh, the Truth. He is best in reward and best in outcome.","tr":"Hunalika alwalayatu lillahialhaqqi huwa khayrun thawaban wakhayrun AAuqba","juz":15,"page":298},{"s":18,"a":45,"key":"18:45","ar":"وَٱضْرِبْ لَهُم مَّثَلَ ٱلْحَيَوٰةِ ٱلدُّنْيَا كَمَآءٍ أَنزَلْنَـٰهُ مِنَ ٱلسَّمَآءِ فَٱخْتَلَطَ بِهِۦ نَبَاتُ ٱلْأَرْضِ فَأَصْبَحَ هَشِيمًا تَذْرُوهُ ٱلرِّيَـٰحُ ۗ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ مُّقْتَدِرًا","en":"And present to them the example of the life of this world, [its being] like rain which We send down from the sky, and the vegetation of the earth mingles with it1 and [then] it becomes dry remnants, scattered by the winds. And Allāh is ever, over all things, Perfect in Ability.","tr":"Wadrib lahum mathala alhayatiaddunya kama-in anzalnahu mina assama-ifakhtalata bihi nabatu al-ardi faasbahahasheeman tathroohu arriyahu wakanaAllahu AAala kulli shay-in muqtadira","juz":15,"page":298},{"s":18,"a":46,"key":"18:46","ar":"ٱلْمَالُ وَٱلْبَنُونَ زِينَةُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَٱلْبَـٰقِيَـٰتُ ٱلصَّـٰلِحَـٰتُ خَيْرٌ عِندَ رَبِّكَ ثَوَابًا وَخَيْرٌ أَمَلًا","en":"Wealth and children are [but] adornment of the worldly life. But the enduring good deeds are better to your Lord1 for reward and better for [one's] hope.","tr":"Almalu walbanoona zeenatu alhayatiaddunya walbaqiyatu assalihatukhayrun AAinda rabbika thawaban wakhayrun amala","juz":15,"page":299},{"s":18,"a":47,"key":"18:47","ar":"وَيَوْمَ نُسَيِّرُ ٱلْجِبَالَ وَتَرَى ٱلْأَرْضَ بَارِزَةً وَحَشَرْنَـٰهُمْ فَلَمْ نُغَادِرْ مِنْهُمْ أَحَدًا","en":"And [warn of] the Day when We will remove the mountains and you will see the earth exposed,1 and We will gather them and not leave behind from them anyone.","tr":"Wayawma nusayyiru aljibala wataraal-arda barizatan wahasharnahum falamnughadir minhum ahada","juz":15,"page":299},{"s":18,"a":48,"key":"18:48","ar":"وَعُرِضُوا۟ عَلَىٰ رَبِّكَ صَفًّا لَّقَدْ جِئْتُمُونَا كَمَا خَلَقْنَـٰكُمْ أَوَّلَ مَرَّةٍۭ ۚ بَلْ زَعَمْتُمْ أَلَّن نَّجْعَلَ لَكُم مَّوْعِدًا","en":"And they will be presented before your Lord in rows, [and He will say], \"You have certainly come to Us just as We created you the first time. But you claimed that We would never make for you an appointment.\"","tr":"WaAAuridoo AAala rabbika saffanlaqad ji/tumoona kama khalaqnakum awwalamarratin bal zaAAamtum allan najAAala lakum mawAAida","juz":15,"page":299},{"s":18,"a":49,"key":"18:49","ar":"وَوُضِعَ ٱلْكِتَـٰبُ فَتَرَى ٱلْمُجْرِمِينَ مُشْفِقِينَ مِمَّا فِيهِ وَيَقُولُونَ يَـٰوَيْلَتَنَا مَالِ هَـٰذَا ٱلْكِتَـٰبِ لَا يُغَادِرُ صَغِيرَةً وَلَا كَبِيرَةً إِلَّآ أَحْصَىٰهَا ۚ وَوَجَدُوا۟ مَا عَمِلُوا۟ حَاضِرًا ۗ وَلَا يَظْلِمُ رَبُّكَ أَحَدًا","en":"And the record [of deeds] will be placed [open], and you will see the criminals fearful of that within it, and they will say, \"Oh, woe to us! What is this book that leaves nothing small or great except that it has enumerated it?\" And they will find what they did present [before them]. And your Lord does injustice to no one.","tr":"WawudiAAa alkitabu fataraalmujrimeena mushfiqeena mimma feehi wayaqooloona yawaylatana ma lihatha alkitabi layughadiru sagheeratan wala kabeeratan illaahsaha wawajadoo ma AAamiloo hadiranwala yathlimu rabbuka ahada","juz":15,"page":299},{"s":18,"a":50,"key":"18:50","ar":"وَإِذْ قُلْنَا لِلْمَلَـٰٓئِكَةِ ٱسْجُدُوا۟ لِـَٔادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ كَانَ مِنَ ٱلْجِنِّ فَفَسَقَ عَنْ أَمْرِ رَبِّهِۦٓ ۗ أَفَتَتَّخِذُونَهُۥ وَذُرِّيَّتَهُۥٓ أَوْلِيَآءَ مِن دُونِى وَهُمْ لَكُمْ عَدُوٌّۢ ۚ بِئْسَ لِلظَّـٰلِمِينَ بَدَلًا","en":"And [mention] when We said to the angels, \"Prostrate to Adam,\" and they prostrated, except for Iblees. He was of the jinn and departed from [i.e., disobeyed] the command of his Lord. Then will you take him and his descendants as allies other than Me while they are enemies to you? Wretched it is for the wrongdoers as an exchange.","tr":"Wa-ith qulna lilmala-ikatiosjudoo li-adama fasajadoo illa ibleesa kanamina aljinni fafasaqa AAan amri rabbihi afatattakhithoonahuwathurriyyatahu awliyaa min doonee wahum lakumAAaduwwun bi/sa liththalimeena badala","juz":15,"page":299},{"s":18,"a":51,"key":"18:51","ar":"۞ مَّآ أَشْهَدتُّهُمْ خَلْقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَلَا خَلْقَ أَنفُسِهِمْ وَمَا كُنتُ مُتَّخِذَ ٱلْمُضِلِّينَ عَضُدًا","en":"I did not make them witness to the creation of the heavens and the earth or to the creation of themselves, and I would not have taken the misguiders as assistants.","tr":"Ma ashhadtuhum khalqa assamawatiwal-ardi wala khalqa anfusihim wamakuntu muttakhitha almudilleena AAaduda","juz":15,"page":299},{"s":18,"a":52,"key":"18:52","ar":"وَيَوْمَ يَقُولُ نَادُوا۟ شُرَكَآءِىَ ٱلَّذِينَ زَعَمْتُمْ فَدَعَوْهُمْ فَلَمْ يَسْتَجِيبُوا۟ لَهُمْ وَجَعَلْنَا بَيْنَهُم مَّوْبِقًا","en":"And [warn of] the Day when He will say, \"Call My 'partners' whom you claimed,\" and they will invoke them, but they will not respond to them. And We will put between them [a valley of] destruction.","tr":"Wayawma yaqoolu nadoo shuraka-iyaallatheena zaAAamtum fadaAAawhum falam yastajeeboo lahumwajaAAalna baynahum mawbiqa","juz":15,"page":299},{"s":18,"a":53,"key":"18:53","ar":"وَرَءَا ٱلْمُجْرِمُونَ ٱلنَّارَ فَظَنُّوٓا۟ أَنَّهُم مُّوَاقِعُوهَا وَلَمْ يَجِدُوا۟ عَنْهَا مَصْرِفًا","en":"And the criminals will see the Fire and will be certain that they are to fall therein. And they will not find from it a way elsewhere.","tr":"Waraa almujrimoona annarafathannoo annahum muwaqiAAooha walamyajidoo AAanha masrifa","juz":15,"page":299},{"s":18,"a":54,"key":"18:54","ar":"وَلَقَدْ صَرَّفْنَا فِى هَـٰذَا ٱلْقُرْءَانِ لِلنَّاسِ مِن كُلِّ مَثَلٍ ۚ وَكَانَ ٱلْإِنسَـٰنُ أَكْثَرَ شَىْءٍ جَدَلًا","en":"And We have certainly diversified in this Qur’ān for the people from every [kind of] example; but man has ever been, most of anything, [prone to] dispute.","tr":"Walaqad sarrafna fee hathaalqur-ani linnasi min kulli mathalin wakanaal-insanu akthara shay-in jadala","juz":15,"page":300},{"s":18,"a":55,"key":"18:55","ar":"وَمَا مَنَعَ ٱلنَّاسَ أَن يُؤْمِنُوٓا۟ إِذْ جَآءَهُمُ ٱلْهُدَىٰ وَيَسْتَغْفِرُوا۟ رَبَّهُمْ إِلَّآ أَن تَأْتِيَهُمْ سُنَّةُ ٱلْأَوَّلِينَ أَوْ يَأْتِيَهُمُ ٱلْعَذَابُ قُبُلًا","en":"And nothing has prevented the people from believing when guidance came to them and from asking forgiveness of their Lord except that there [must] befall them the [accustomed] precedent of the former peoples1 or that the punishment should come [directly] before them.","tr":"Wama manaAAa annasa anyu/minoo ith jaahumu alhuda wayastaghfiroorabbahum illa an ta/tiyahum sunnatu al-awwaleena awya/tiyahumu alAAathabu qubula","juz":15,"page":300},{"s":18,"a":56,"key":"18:56","ar":"وَمَا نُرْسِلُ ٱلْمُرْسَلِينَ إِلَّا مُبَشِّرِينَ وَمُنذِرِينَ ۚ وَيُجَـٰدِلُ ٱلَّذِينَ كَفَرُوا۟ بِٱلْبَـٰطِلِ لِيُدْحِضُوا۟ بِهِ ٱلْحَقَّ ۖ وَٱتَّخَذُوٓا۟ ءَايَـٰتِى وَمَآ أُنذِرُوا۟ هُزُوًا","en":"And We send not the messengers except as bringers of good tidings and warners. And those who disbelieve dispute by [using] falsehood to [attempt to] invalidate thereby the truth and have taken My verses, and that of which they are warned, in ridicule.","tr":"Wama nursilu almursaleena illamubashshireena wamunthireena wayujadilu allatheenakafaroo bilbatili liyudhidoo bihi alhaqqawattakhathoo ayatee wama onthiroohuzuwa","juz":15,"page":300},{"s":18,"a":57,"key":"18:57","ar":"وَمَنْ أَظْلَمُ مِمَّن ذُكِّرَ بِـَٔايَـٰتِ رَبِّهِۦ فَأَعْرَضَ عَنْهَا وَنَسِىَ مَا قَدَّمَتْ يَدَاهُ ۚ إِنَّا جَعَلْنَا عَلَىٰ قُلُوبِهِمْ أَكِنَّةً أَن يَفْقَهُوهُ وَفِىٓ ءَاذَانِهِمْ وَقْرًا ۖ وَإِن تَدْعُهُمْ إِلَى ٱلْهُدَىٰ فَلَن يَهْتَدُوٓا۟ إِذًا أَبَدًا","en":"And who is more unjust than one who is reminded of the verses of his Lord but turns away from them and forgets what his hands have put forth? Indeed, We have placed over their hearts coverings, lest they understand it, and in their ears deafness. And if you invite them to guidance - they will never be guided, then - ever.","tr":"Waman athlamu mimman thukkirabi-ayati rabbihi faaAArada AAanhawanasiya ma qaddamat yadahu inna jaAAalnaAAala quloobihim akinnatan an yafqahoohu wafee athanihimwaqran wa-in tadAAuhum ila alhuda falan yahtadoo ithanabada","juz":15,"page":300},{"s":18,"a":58,"key":"18:58","ar":"وَرَبُّكَ ٱلْغَفُورُ ذُو ٱلرَّحْمَةِ ۖ لَوْ يُؤَاخِذُهُم بِمَا كَسَبُوا۟ لَعَجَّلَ لَهُمُ ٱلْعَذَابَ ۚ بَل لَّهُم مَّوْعِدٌ لَّن يَجِدُوا۟ مِن دُونِهِۦ مَوْئِلًا","en":"And your Lord is the Forgiving, the possessor of mercy. If He were to impose blame upon them for what they earned, He would have hastened for them the punishment. Rather, for them is an appointment from which they will never find an escape.","tr":"Warabbuka alghafooru thoo arrahmatilaw yu-akhithuhum bima kasaboo laAAajjalalahumu alAAathaba bal lahum mawAAidun lan yajidoo mindoonihi maw-ila","juz":15,"page":300},{"s":18,"a":59,"key":"18:59","ar":"وَتِلْكَ ٱلْقُرَىٰٓ أَهْلَكْنَـٰهُمْ لَمَّا ظَلَمُوا۟ وَجَعَلْنَا لِمَهْلِكِهِم مَّوْعِدًا","en":"And those cities - We destroyed them when they wronged, and We made for their destruction an appointed time.","tr":"Watilka alqura ahlaknahum lammathalamoo wajaAAalna limahlikihim mawAAida","juz":15,"page":300},{"s":18,"a":60,"key":"18:60","ar":"وَإِذْ قَالَ مُوسَىٰ لِفَتَىٰهُ لَآ أَبْرَحُ حَتَّىٰٓ أَبْلُغَ مَجْمَعَ ٱلْبَحْرَيْنِ أَوْ أَمْضِىَ حُقُبًا","en":"And [mention] when Moses said to his boy [i.e., servant], \"I will not cease [traveling] until I reach the junction of the two seas or continue for a long period.\"","tr":"Wa-ith qala moosa lifatahula abrahu hatta ablugha majmaAAa albahrayniaw amdiya huquba","juz":15,"page":300},{"s":18,"a":61,"key":"18:61","ar":"فَلَمَّا بَلَغَا مَجْمَعَ بَيْنِهِمَا نَسِيَا حُوتَهُمَا فَٱتَّخَذَ سَبِيلَهُۥ فِى ٱلْبَحْرِ سَرَبًا","en":"But when they reached the junction between them, they forgot their fish, and it took its course into the sea, slipping away.","tr":"Falamma balagha majmaAAabaynihima nasiya hootahuma fattakhathasabeelahu fee albahri saraba","juz":15,"page":300},{"s":18,"a":62,"key":"18:62","ar":"فَلَمَّا جَاوَزَا قَالَ لِفَتَىٰهُ ءَاتِنَا غَدَآءَنَا لَقَدْ لَقِينَا مِن سَفَرِنَا هَـٰذَا نَصَبًا","en":"So when they had passed beyond it, [Moses] said to his boy, \"Bring us our morning meal. We have certainly suffered in this, our journey, [much] fatigue.\"","tr":"Falamma jawaza qalalifatahu atina ghadaana laqadlaqeena min safarina hatha nasaba","juz":15,"page":301},{"s":18,"a":63,"key":"18:63","ar":"قَالَ أَرَءَيْتَ إِذْ أَوَيْنَآ إِلَى ٱلصَّخْرَةِ فَإِنِّى نَسِيتُ ٱلْحُوتَ وَمَآ أَنسَىٰنِيهُ إِلَّا ٱلشَّيْطَـٰنُ أَنْ أَذْكُرَهُۥ ۚ وَٱتَّخَذَ سَبِيلَهُۥ فِى ٱلْبَحْرِ عَجَبًا","en":"He said, \"Did you see when we retired to the rock? Indeed, I forgot [there] the fish. And none made me forget it except Satan - that I should mention it. And it took its course into the sea amazingly.\"","tr":"Qala araayta ith awaynaila assakhrati fa-innee naseetu alhootawama ansaneehu illa ashshaytanuan athkurahu wattakhatha sabeelahu fee albahriAAajaba","juz":15,"page":301},{"s":18,"a":64,"key":"18:64","ar":"قَالَ ذَٰلِكَ مَا كُنَّا نَبْغِ ۚ فَٱرْتَدَّا عَلَىٰٓ ءَاثَارِهِمَا قَصَصًا","en":"[Moses] said, \"That is what we were seeking.\" So they returned, following their footprints.","tr":"Qala thalika ma kunnanabghi fartadda AAala atharihimaqasasa","juz":15,"page":301},{"s":18,"a":65,"key":"18:65","ar":"فَوَجَدَا عَبْدًا مِّنْ عِبَادِنَآ ءَاتَيْنَـٰهُ رَحْمَةً مِّنْ عِندِنَا وَعَلَّمْنَـٰهُ مِن لَّدُنَّا عِلْمًا","en":"And they found a servant from among Our servants [i.e., al-Khiḍr] to whom We had given mercy from Us and had taught him from Us a [certain] knowledge.","tr":"Fawajada AAabdan min AAibadinaataynahu rahmatan min AAindinawaAAallamnahu min ladunna AAilma","juz":15,"page":301},{"s":18,"a":66,"key":"18:66","ar":"قَالَ لَهُۥ مُوسَىٰ هَلْ أَتَّبِعُكَ عَلَىٰٓ أَن تُعَلِّمَنِ مِمَّا عُلِّمْتَ رُشْدًا","en":"Moses said to him, \"May I follow you on [the condition] that you teach me from what you have been taught of sound judgement?\"","tr":"Qala lahu moosa halattabiAAuka AAala an tuAAallimani mimma AAullimtarushda","juz":15,"page":301},{"s":18,"a":67,"key":"18:67","ar":"قَالَ إِنَّكَ لَن تَسْتَطِيعَ مَعِىَ صَبْرًا","en":"He said, \"Indeed, with me you will never be able to have patience.","tr":"Qala innaka lan tastateeAAamaAAiya sabra","juz":15,"page":301},{"s":18,"a":68,"key":"18:68","ar":"وَكَيْفَ تَصْبِرُ عَلَىٰ مَا لَمْ تُحِطْ بِهِۦ خُبْرًا","en":"And how can you have patience for what you do not encompass in knowledge?\"","tr":"Wakayfa tasbiru AAala malam tuhit bihi khubra","juz":15,"page":301},{"s":18,"a":69,"key":"18:69","ar":"قَالَ سَتَجِدُنِىٓ إِن شَآءَ ٱللَّهُ صَابِرًا وَلَآ أَعْصِى لَكَ أَمْرًا","en":"[Moses] said, \"You will find me, if Allāh wills, patient, and I will not disobey you in [any] order.\"","tr":"Qala satajidunee in shaa Allahusabiran wala aAAsee laka amra","juz":15,"page":301},{"s":18,"a":70,"key":"18:70","ar":"قَالَ فَإِنِ ٱتَّبَعْتَنِى فَلَا تَسْـَٔلْنِى عَن شَىْءٍ حَتَّىٰٓ أُحْدِثَ لَكَ مِنْهُ ذِكْرًا","en":"He said, \"Then if you follow me, do not ask me about anything until I make to you about it mention [i.e., explanation].\"","tr":"Qala fa-ini ittabaAAtanee falatas-alnee AAan shay-in hatta ohditha lakaminhu thikra","juz":15,"page":301},{"s":18,"a":71,"key":"18:71","ar":"فَٱنطَلَقَا حَتَّىٰٓ إِذَا رَكِبَا فِى ٱلسَّفِينَةِ خَرَقَهَا ۖ قَالَ أَخَرَقْتَهَا لِتُغْرِقَ أَهْلَهَا لَقَدْ جِئْتَ شَيْـًٔا إِمْرًا","en":"So they set out, until when they had embarked on the ship, he [i.e., al-Khiḍr] tore it open. [Moses] said, \"Have you torn it open to drown its people? You have certainly done a grave thing.\"","tr":"Fantalaqa hattaitha rakiba fee assafeenati kharaqahaqala akharaqtaha litughriqa ahlaha laqadji/ta shay-an imra","juz":15,"page":301},{"s":18,"a":72,"key":"18:72","ar":"قَالَ أَلَمْ أَقُلْ إِنَّكَ لَن تَسْتَطِيعَ مَعِىَ صَبْرًا","en":"[Al-Khiḍr] said, \"Did I not say that with me you would never be able to have patience?\"","tr":"Qala alam aqul innaka lan tastateeAAamaAAiya sabra","juz":15,"page":301},{"s":18,"a":73,"key":"18:73","ar":"قَالَ لَا تُؤَاخِذْنِى بِمَا نَسِيتُ وَلَا تُرْهِقْنِى مِنْ أَمْرِى عُسْرًا","en":"[Moses] said, \"Do not blame me for what I forgot and do not overwhelm me in my matter with difficulty.\"","tr":"Qala la tu-akhithneebima naseetu wala turhiqnee min amree AAusra","juz":15,"page":301},{"s":18,"a":74,"key":"18:74","ar":"فَٱنطَلَقَا حَتَّىٰٓ إِذَا لَقِيَا غُلَـٰمًا فَقَتَلَهُۥ قَالَ أَقَتَلْتَ نَفْسًا زَكِيَّةًۢ بِغَيْرِ نَفْسٍ لَّقَدْ جِئْتَ شَيْـًٔا نُّكْرًا","en":"So they set out, until when they met a boy, he [i.e., al-Khiḍr] killed him. [Moses] said, \"Have you killed a pure soul for other than [having killed] a soul? You have certainly done a deplorable thing.\"","tr":"Fantalaqa hattaitha laqiya ghulaman faqatalahu qalaaqatalta nafsan zakiyyatan bighayri nafsin laqad ji/ta shay-annukra","juz":15,"page":301},{"s":18,"a":75,"key":"18:75","ar":"۞ قَالَ أَلَمْ أَقُل لَّكَ إِنَّكَ لَن تَسْتَطِيعَ مَعِىَ صَبْرًا","en":"[Al-Khiḍr] said, \"Did I not tell you that with me you would never be able to have patience?\"","tr":"Qala alam aqul laka innaka lan tastateeAAamaAAiya sabra","juz":16,"page":302},{"s":18,"a":76,"key":"18:76","ar":"قَالَ إِن سَأَلْتُكَ عَن شَىْءٍۭ بَعْدَهَا فَلَا تُصَـٰحِبْنِى ۖ قَدْ بَلَغْتَ مِن لَّدُنِّى عُذْرًا","en":"[Moses] said, \"If I should ask you about anything after this, then do not keep me as a companion. You have obtained from me an excuse.\"","tr":"Qala in saaltuka AAan shay-in baAAdahafala tusahibnee qad balaghta min ladunnee AAuthra","juz":16,"page":302},{"s":18,"a":77,"key":"18:77","ar":"فَٱنطَلَقَا حَتَّىٰٓ إِذَآ أَتَيَآ أَهْلَ قَرْيَةٍ ٱسْتَطْعَمَآ أَهْلَهَا فَأَبَوْا۟ أَن يُضَيِّفُوهُمَا فَوَجَدَا فِيهَا جِدَارًا يُرِيدُ أَن يَنقَضَّ فَأَقَامَهُۥ ۖ قَالَ لَوْ شِئْتَ لَتَّخَذْتَ عَلَيْهِ أَجْرًا","en":"So they set out, until when they came to the people of a town, they asked its people for food, but they refused to offer them hospitality. And they found therein a wall about to collapse, so he [i.e., al-Khiḍr] restored it. [Moses] said, \"If you wished, you could have taken for it a payment.\"","tr":"Fantalaqa hattaitha ataya ahla qaryatin istatAAamaahlaha faabaw an yudayyifoohuma fawajadafeeha jidaran yureedu an yanqadda faaqamahuqala law shi/ta lattakhathta AAalayhi ajra","juz":16,"page":302},{"s":18,"a":78,"key":"18:78","ar":"قَالَ هَـٰذَا فِرَاقُ بَيْنِى وَبَيْنِكَ ۚ سَأُنَبِّئُكَ بِتَأْوِيلِ مَا لَمْ تَسْتَطِع عَّلَيْهِ صَبْرًا","en":"[Al-Khiḍr] said, \"This is parting between me and you. I will inform you of the interpretation of that about which you could not have patience.","tr":"Qala hatha firaqubaynee wabaynika saonabbi-oka bita/weeli ma lam tastatiAAAAalayhi sabra","juz":16,"page":302},{"s":18,"a":79,"key":"18:79","ar":"أَمَّا ٱلسَّفِينَةُ فَكَانَتْ لِمَسَـٰكِينَ يَعْمَلُونَ فِى ٱلْبَحْرِ فَأَرَدتُّ أَنْ أَعِيبَهَا وَكَانَ وَرَآءَهُم مَّلِكٌ يَأْخُذُ كُلَّ سَفِينَةٍ غَصْبًا","en":"As for the ship, it belonged to poor people working at sea. So I intended to cause defect in it as there was after them a king who seized every [good] ship by force.","tr":"Amma assafeenatu fakanatlimasakeena yaAAmaloona fee albahri faaradtu anaAAeebaha wakana waraahum malikun ya/khuthukulla safeenatin ghasba","juz":16,"page":302},{"s":18,"a":80,"key":"18:80","ar":"وَأَمَّا ٱلْغُلَـٰمُ فَكَانَ أَبَوَاهُ مُؤْمِنَيْنِ فَخَشِينَآ أَن يُرْهِقَهُمَا طُغْيَـٰنًا وَكُفْرًا","en":"And as for the boy, his parents were believers, and we feared that he would overburden them by transgression and disbelief.","tr":"Waamma alghulamu fakanaabawahu mu/minayni fakhasheena an yurhiqahumatughyanan wakufra","juz":16,"page":302},{"s":18,"a":81,"key":"18:81","ar":"فَأَرَدْنَآ أَن يُبْدِلَهُمَا رَبُّهُمَا خَيْرًا مِّنْهُ زَكَوٰةً وَأَقْرَبَ رُحْمًا","en":"So we intended that their Lord should substitute for them one better than him in purity and nearer to mercy.","tr":"Faaradna an yubdilahumarabbuhuma khayran minhu zakatan waaqraba ruhma","juz":16,"page":302},{"s":18,"a":82,"key":"18:82","ar":"وَأَمَّا ٱلْجِدَارُ فَكَانَ لِغُلَـٰمَيْنِ يَتِيمَيْنِ فِى ٱلْمَدِينَةِ وَكَانَ تَحْتَهُۥ كَنزٌ لَّهُمَا وَكَانَ أَبُوهُمَا صَـٰلِحًا فَأَرَادَ رَبُّكَ أَن يَبْلُغَآ أَشُدَّهُمَا وَيَسْتَخْرِجَا كَنزَهُمَا رَحْمَةً مِّن رَّبِّكَ ۚ وَمَا فَعَلْتُهُۥ عَنْ أَمْرِى ۚ ذَٰلِكَ تَأْوِيلُ مَا لَمْ تَسْطِع عَّلَيْهِ صَبْرًا","en":"And as for the wall, it belonged to two orphan boys in the city, and there was beneath it a treasure for them, and their father had been righteous. So your Lord intended that they reach maturity and extract their treasure, as a mercy from your Lord. And I did it not of my own accord. That is the interpretation of that about which you could not have patience.\"","tr":"Waamma aljidaru fakanalighulamayni yateemayni fee almadeenati wakana tahtahukanzun lahuma wakana aboohuma salihanfaarada rabbuka an yablugha ashuddahumawayastakhrija kanzahuma rahmatan min rabbikawama faAAaltuhu AAan amree thalika ta/weelu malam tastiAA AAalayhi sabra","juz":16,"page":302},{"s":18,"a":83,"key":"18:83","ar":"وَيَسْـَٔلُونَكَ عَن ذِى ٱلْقَرْنَيْنِ ۖ قُلْ سَأَتْلُوا۟ عَلَيْكُم مِّنْهُ ذِكْرًا","en":"And they ask you, [O Muḥammad], about Dhul-Qarnayn. Say, \"I will recite to you about him a report.\"","tr":"Wayas-aloonaka AAan thee alqarnayniqul saatloo AAalaykum minhu thikra","juz":16,"page":302},{"s":18,"a":84,"key":"18:84","ar":"إِنَّا مَكَّنَّا لَهُۥ فِى ٱلْأَرْضِ وَءَاتَيْنَـٰهُ مِن كُلِّ شَىْءٍ سَبَبًا","en":"Indeed, We established him upon the earth, and We gave him from everything a way [i.e., means].","tr":"Inna makkanna lahu fee al-ardiwaataynahu min kulli shay-in sababa","juz":16,"page":303},{"s":18,"a":85,"key":"18:85","ar":"فَأَتْبَعَ سَبَبًا","en":"So he followed a way","tr":"FaatbaAAa sababa","juz":16,"page":303},{"s":18,"a":86,"key":"18:86","ar":"حَتَّىٰٓ إِذَا بَلَغَ مَغْرِبَ ٱلشَّمْسِ وَجَدَهَا تَغْرُبُ فِى عَيْنٍ حَمِئَةٍ وَوَجَدَ عِندَهَا قَوْمًا ۗ قُلْنَا يَـٰذَا ٱلْقَرْنَيْنِ إِمَّآ أَن تُعَذِّبَ وَإِمَّآ أَن تَتَّخِذَ فِيهِمْ حُسْنًا","en":"Until, when he reached the setting of the sun [i.e., the west], he found it [as if] setting in a body of dark water,1 and he found near it a people. We [i.e., Allāh] said, \"O Dhul-Qarnayn, either you punish [them] or else adopt among them [a way of] goodness.\"","tr":"Hatta itha balaghamaghriba ashshamsi wajadaha taghrubu fee AAaynin hami-atinwawajada AAindaha qawman qulna ya thaalqarnayni imma an tuAAaththiba wa-imma antattakhitha feehim husna","juz":16,"page":303},{"s":18,"a":87,"key":"18:87","ar":"قَالَ أَمَّا مَن ظَلَمَ فَسَوْفَ نُعَذِّبُهُۥ ثُمَّ يُرَدُّ إِلَىٰ رَبِّهِۦ فَيُعَذِّبُهُۥ عَذَابًا نُّكْرًا","en":"He said, \"As for one who wrongs,1 we will punish him. Then he will be returned to his Lord, and He will punish him with a terrible punishment [i.e., Hellfire].","tr":"Qala amma man thalamafasawfa nuAAaththibuhu thumma yuraddu ila rabbihifayuAAaththibuhu AAathaban nukra","juz":16,"page":303},{"s":18,"a":88,"key":"18:88","ar":"وَأَمَّا مَنْ ءَامَنَ وَعَمِلَ صَـٰلِحًا فَلَهُۥ جَزَآءً ٱلْحُسْنَىٰ ۖ وَسَنَقُولُ لَهُۥ مِنْ أَمْرِنَا يُسْرًا","en":"But as for one who believes and does righteousness, he will have a reward of the best [i.e., Paradise], and we [i.e., Dhul-Qarnayn] will speak to him from our command with ease.\"","tr":"Waamma man amana waAAamila salihanfalahu jazaan alhusna wasanaqoolu lahu minamrina yusra","juz":16,"page":303},{"s":18,"a":89,"key":"18:89","ar":"ثُمَّ أَتْبَعَ سَبَبًا","en":"Then he followed a way","tr":"Thumma atbaAAa sababa","juz":16,"page":303},{"s":18,"a":90,"key":"18:90","ar":"حَتَّىٰٓ إِذَا بَلَغَ مَطْلِعَ ٱلشَّمْسِ وَجَدَهَا تَطْلُعُ عَلَىٰ قَوْمٍ لَّمْ نَجْعَل لَّهُم مِّن دُونِهَا سِتْرًا","en":"Until, when he came to the rising of the sun [i.e., the east], he found it rising on a people for whom We had not made against it any shield.","tr":"Hatta itha balagha matliAAaashshamsi wajadaha tatluAAu AAalaqawmin lam najAAal lahum min dooniha sitra","juz":16,"page":303},{"s":18,"a":91,"key":"18:91","ar":"كَذَٰلِكَ وَقَدْ أَحَطْنَا بِمَا لَدَيْهِ خُبْرًا","en":"Thus.1 And We had encompassed [all] that he had in knowledge.","tr":"Kathalika waqad ahatnabima ladayhi khubra","juz":16,"page":303},{"s":18,"a":92,"key":"18:92","ar":"ثُمَّ أَتْبَعَ سَبَبًا","en":"Then he followed a way.","tr":"Thumma atbaAAa sababa","juz":16,"page":303},{"s":18,"a":93,"key":"18:93","ar":"حَتَّىٰٓ إِذَا بَلَغَ بَيْنَ ٱلسَّدَّيْنِ وَجَدَ مِن دُونِهِمَا قَوْمًا لَّا يَكَادُونَ يَفْقَهُونَ قَوْلًا","en":"Until, when he reached [a pass] between two mountains, he found beside them a people who could hardly understand [his] speech.","tr":"Hatta itha balaghabayna assaddayni wajada min doonihima qawman layakadoona yafqahoona qawla","juz":16,"page":303},{"s":18,"a":94,"key":"18:94","ar":"قَالُوا۟ يَـٰذَا ٱلْقَرْنَيْنِ إِنَّ يَأْجُوجَ وَمَأْجُوجَ مُفْسِدُونَ فِى ٱلْأَرْضِ فَهَلْ نَجْعَلُ لَكَ خَرْجًا عَلَىٰٓ أَن تَجْعَلَ بَيْنَنَا وَبَيْنَهُمْ سَدًّا","en":"They said, \"O Dhul-Qarnayn, indeed Gog and Magog1 are [great] corrupters in the land. So may we assign for you an expenditure that you might make between us and them a barrier?\"","tr":"Qaloo ya tha alqarnayniinna ya/jooja wama/jooja mufsidoona fee al-ardi fahalnajAAalu laka kharjan AAala an tajAAala baynanawabaynahum sadda","juz":16,"page":303},{"s":18,"a":95,"key":"18:95","ar":"قَالَ مَا مَكَّنِّى فِيهِ رَبِّى خَيْرٌ فَأَعِينُونِى بِقُوَّةٍ أَجْعَلْ بَيْنَكُمْ وَبَيْنَهُمْ رَدْمًا","en":"He said, \"That in which my Lord has established me is better [than what you offer], but assist me with strength [i.e., manpower]; I will make between you and them a dam.","tr":"Qala ma makkannee feehi rabbeekhayrun faaAAeenoonee biquwwatin ajAAal baynakum wabaynahum radma","juz":16,"page":303},{"s":18,"a":96,"key":"18:96","ar":"ءَاتُونِى زُبَرَ ٱلْحَدِيدِ ۖ حَتَّىٰٓ إِذَا سَاوَىٰ بَيْنَ ٱلصَّدَفَيْنِ قَالَ ٱنفُخُوا۟ ۖ حَتَّىٰٓ إِذَا جَعَلَهُۥ نَارًا قَالَ ءَاتُونِىٓ أُفْرِغْ عَلَيْهِ قِطْرًا","en":"Bring me bars of iron\" - until, when he had leveled [them] between the two mountain walls, he said, \"Blow [with bellows],\" until when he had made it [like] fire, he said, \"Bring me, that I may pour over it molten copper.\"","tr":"Atoonee zubara alhadeedi hattaitha sawa bayna asadafayni qalaonfukhoo hatta itha jaAAalahu naran qalaatoonee ofrigh AAalayhi qitra","juz":16,"page":303},{"s":18,"a":97,"key":"18:97","ar":"فَمَا ٱسْطَـٰعُوٓا۟ أَن يَظْهَرُوهُ وَمَا ٱسْتَطَـٰعُوا۟ لَهُۥ نَقْبًا","en":"So they [i.e., Gog and Magog] were unable to pass over it, nor were they able [to effect] in it any penetration.","tr":"Fama istaAAoo an yathharoohuwama istataAAoo lahu naqba","juz":16,"page":303},{"s":18,"a":98,"key":"18:98","ar":"قَالَ هَـٰذَا رَحْمَةٌ مِّن رَّبِّى ۖ فَإِذَا جَآءَ وَعْدُ رَبِّى جَعَلَهُۥ دَكَّآءَ ۖ وَكَانَ وَعْدُ رَبِّى حَقًّا","en":"[Dhul-Qarnayn] said, \"This is a mercy from my Lord; but when the promise of my Lord1 comes [i.e., approaches], He will make it level, and ever is the promise of my Lord true.\"","tr":"Qala hatha rahmatun minrabbee fa-itha jaa waAAdu rabbee jaAAalahu dakkaawakana waAAdu rabbee haqqa","juz":16,"page":304},{"s":18,"a":99,"key":"18:99","ar":"۞ وَتَرَكْنَا بَعْضَهُمْ يَوْمَئِذٍ يَمُوجُ فِى بَعْضٍ ۖ وَنُفِخَ فِى ٱلصُّورِ فَجَمَعْنَـٰهُمْ جَمْعًا","en":"And We will leave them that day1 surging over each other, and [then] the Horn will be blown, and We will assemble them in [one] assembly.","tr":"Watarakna baAAdahum yawma-ithinyamooju fee baAAdin wanufikha fee assoorifajamaAAnahum jamAAa","juz":16,"page":304},{"s":18,"a":100,"key":"18:100","ar":"وَعَرَضْنَا جَهَنَّمَ يَوْمَئِذٍ لِّلْكَـٰفِرِينَ عَرْضًا","en":"And We will present Hell that Day to the disbelievers, on display -","tr":"WaAAaradna jahannama yawma-ithinlilkafireena AAarda","juz":16,"page":304},{"s":18,"a":101,"key":"18:101","ar":"ٱلَّذِينَ كَانَتْ أَعْيُنُهُمْ فِى غِطَآءٍ عَن ذِكْرِى وَكَانُوا۟ لَا يَسْتَطِيعُونَ سَمْعًا","en":"Those whose eyes had been within a cover [removed] from My remembrance,1 and they were not able to hear.2","tr":"Allatheena kanat aAAyunuhumfee ghita-in AAan thikree wakanoo layastateeAAoona samAAa","juz":16,"page":304},{"s":18,"a":102,"key":"18:102","ar":"أَفَحَسِبَ ٱلَّذِينَ كَفَرُوٓا۟ أَن يَتَّخِذُوا۟ عِبَادِى مِن دُونِىٓ أَوْلِيَآءَ ۚ إِنَّآ أَعْتَدْنَا جَهَنَّمَ لِلْكَـٰفِرِينَ نُزُلًا","en":"Then do those who disbelieve think that they can take My servants instead of Me as allies? Indeed, We have prepared Hell for the disbelievers as a lodging.","tr":"Afahasiba allatheena kafarooan yattakhithoo AAibadee min doonee awliyaainna aAAtadna jahannama lilkafireena nuzula","juz":16,"page":304},{"s":18,"a":103,"key":"18:103","ar":"قُلْ هَلْ نُنَبِّئُكُم بِٱلْأَخْسَرِينَ أَعْمَـٰلًا","en":"Say, [O Muḥammad], \"Shall we [believers] inform you of the greatest losers as to [their] deeds?","tr":"Qul hal nunabbi-okum bil-akhsareenaaAAmala","juz":16,"page":304},{"s":18,"a":104,"key":"18:104","ar":"ٱلَّذِينَ ضَلَّ سَعْيُهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَهُمْ يَحْسَبُونَ أَنَّهُمْ يُحْسِنُونَ صُنْعًا","en":"[They are] those whose effort is lost in worldly life, while they think that they are doing well in work.\"","tr":"Allatheena dalla saAAyuhumfee alhayati addunya wahum yahsaboonaannahum yuhsinoona sunAAa","juz":16,"page":304},{"s":18,"a":105,"key":"18:105","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ كَفَرُوا۟ بِـَٔايَـٰتِ رَبِّهِمْ وَلِقَآئِهِۦ فَحَبِطَتْ أَعْمَـٰلُهُمْ فَلَا نُقِيمُ لَهُمْ يَوْمَ ٱلْقِيَـٰمَةِ وَزْنًا","en":"Those are the ones who disbelieve in the verses of their Lord and in [their] meeting Him, so their deeds have become worthless; and We will not assign to them on the Day of Resurrection any weight [i.e., importance].","tr":"Ola-ika allatheena kafaroobi-ayati rabbihim waliqa-ihi fahabitataAAmaluhum fala nuqeemu lahum yawma alqiyamatiwazna","juz":16,"page":304},{"s":18,"a":106,"key":"18:106","ar":"ذَٰلِكَ جَزَآؤُهُمْ جَهَنَّمُ بِمَا كَفَرُوا۟ وَٱتَّخَذُوٓا۟ ءَايَـٰتِى وَرُسُلِى هُزُوًا","en":"That is their recompense - Hell - for what they denied and [because] they took My signs and My messengers in ridicule.","tr":"Thalika jazaohum jahannamubima kafaroo wattakhathoo ayateewarusulee huzuwa","juz":16,"page":304},{"s":18,"a":107,"key":"18:107","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ كَانَتْ لَهُمْ جَنَّـٰتُ ٱلْفِرْدَوْسِ نُزُلًا","en":"Indeed, those who have believed and done righteous deeds - they will have the Gardens of Paradise1 as a lodging,","tr":"Inna allatheena amanoowaAAamiloo assalihati kanat lahumjannatu alfirdawsi nuzula","juz":16,"page":304},{"s":18,"a":108,"key":"18:108","ar":"خَـٰلِدِينَ فِيهَا لَا يَبْغُونَ عَنْهَا حِوَلًا","en":"Wherein they abide eternally. They will not desire from it any transfer.","tr":"Khalideena feeha layabghoona AAanha hiwala","juz":16,"page":304},{"s":18,"a":109,"key":"18:109","ar":"قُل لَّوْ كَانَ ٱلْبَحْرُ مِدَادًا لِّكَلِمَـٰتِ رَبِّى لَنَفِدَ ٱلْبَحْرُ قَبْلَ أَن تَنفَدَ كَلِمَـٰتُ رَبِّى وَلَوْ جِئْنَا بِمِثْلِهِۦ مَدَدًا","en":"Say, \"If the sea were ink for [writing] the words1 of my Lord, the sea would be exhausted before the words of my Lord were exhausted, even if We brought the like of it in [continual] supplement.\"","tr":"Qul law kana albahru midadanlikalimati rabbee lanafida albahru qabla an tanfadakalimatu rabbee walaw ji/na bimithlihi madada","juz":16,"page":304},{"s":18,"a":110,"key":"18:110","ar":"قُلْ إِنَّمَآ أَنَا۠ بَشَرٌ مِّثْلُكُمْ يُوحَىٰٓ إِلَىَّ أَنَّمَآ إِلَـٰهُكُمْ إِلَـٰهٌ وَٰحِدٌ ۖ فَمَن كَانَ يَرْجُوا۟ لِقَآءَ رَبِّهِۦ فَلْيَعْمَلْ عَمَلًا صَـٰلِحًا وَلَا يُشْرِكْ بِعِبَادَةِ رَبِّهِۦٓ أَحَدًۢا","en":"Say, \"I am only a man like you, to whom has been revealed that your god is one God. So whoever would hope for the meeting with his Lord - let him do righteous work and not associate in the worship of his Lord anyone.\"","tr":"Qul innama ana basharunmithlukum yooha ilayya annama ilahukum ilahunwahidun faman kana yarjoo liqaa rabbihifalyaAAmal AAamalan salihan wala yushrikbiAAibadati rabbihi ahada","juz":16,"page":304},{"s":19,"a":1,"key":"19:1","ar":" كٓهيعٓصٓ","en":"Kāf, Hā, Yā, ʿAyn, Ṣād.1","tr":"Kaf-ha-ya-AAayn-sad","juz":16,"page":305},{"s":19,"a":2,"key":"19:2","ar":"ذِكْرُ رَحْمَتِ رَبِّكَ عَبْدَهُۥ زَكَرِيَّآ","en":"[This is] a mention of the mercy of your Lord to His servant Zechariah","tr":"Thikru rahmati rabbika AAabdahuzakariyya","juz":16,"page":305},{"s":19,"a":3,"key":"19:3","ar":"إِذْ نَادَىٰ رَبَّهُۥ نِدَآءً خَفِيًّا","en":"When he called to his Lord a private call [i.e., supplication].","tr":"Ith nada rabbahu nidaankhafiyya","juz":16,"page":305},{"s":19,"a":4,"key":"19:4","ar":"قَالَ رَبِّ إِنِّى وَهَنَ ٱلْعَظْمُ مِنِّى وَٱشْتَعَلَ ٱلرَّأْسُ شَيْبًا وَلَمْ أَكُنۢ بِدُعَآئِكَ رَبِّ شَقِيًّا","en":"He said, \"My Lord, indeed my bones have weakened, and my head has filled1 with white, and never have I been in my supplication to You, my Lord, unhappy [i.e., disappointed].","tr":"Qala rabbi innee wahana alAAathmuminnee washtaAAala arra/su shayban walam akunbiduAAa-ika rabbi shaqiyya","juz":16,"page":305},{"s":19,"a":5,"key":"19:5","ar":"وَإِنِّى خِفْتُ ٱلْمَوَٰلِىَ مِن وَرَآءِى وَكَانَتِ ٱمْرَأَتِى عَاقِرًا فَهَبْ لِى مِن لَّدُنكَ وَلِيًّا","en":"And indeed, I fear the successors1 after me, and my wife has been barren, so give me from Yourself an heir","tr":"Wa-innee khiftu almawaliya min wara-eewakanati imraatee AAaqiran fahab lee min ladunkawaliyya","juz":16,"page":305},{"s":19,"a":6,"key":"19:6","ar":"يَرِثُنِى وَيَرِثُ مِنْ ءَالِ يَعْقُوبَ ۖ وَٱجْعَلْهُ رَبِّ رَضِيًّا","en":"Who will inherit me1 and inherit from the family of Jacob. And make him, my Lord, pleasing [to You].\"","tr":"Yarithunee wayarithu min ali yaAAqoobawajAAalhu rabbi radiyya","juz":16,"page":305},{"s":19,"a":7,"key":"19:7","ar":"يَـٰزَكَرِيَّآ إِنَّا نُبَشِّرُكَ بِغُلَـٰمٍ ٱسْمُهُۥ يَحْيَىٰ لَمْ نَجْعَل لَّهُۥ مِن قَبْلُ سَمِيًّا","en":"[He was told],1 \"O Zechariah, indeed We give you good tidings of a boy whose name will be John. We have not assigned to any before [this] name.\"","tr":"Ya zakariyya innanubashshiruka bighulamin ismuhu yahya lamnajAAal lahu min qablu samiyya","juz":16,"page":305},{"s":19,"a":8,"key":"19:8","ar":"قَالَ رَبِّ أَنَّىٰ يَكُونُ لِى غُلَـٰمٌ وَكَانَتِ ٱمْرَأَتِى عَاقِرًا وَقَدْ بَلَغْتُ مِنَ ٱلْكِبَرِ عِتِيًّا","en":"He said, \"My Lord, how will I have a boy when my wife has been barren and I have reached extreme old age?\"","tr":"Qala rabbi anna yakoonu leeghulamun wakanati imraatee AAaqiran waqadbalaghtu mina alkibari AAitiyya","juz":16,"page":305},{"s":19,"a":9,"key":"19:9","ar":"قَالَ كَذَٰلِكَ قَالَ رَبُّكَ هُوَ عَلَىَّ هَيِّنٌ وَقَدْ خَلَقْتُكَ مِن قَبْلُ وَلَمْ تَكُ شَيْـًٔا","en":"[An angel] said, \"Thus [it will be]; your Lord says, 'It is easy for Me, for I created you before, while you were nothing.'\"","tr":"Qala kathalika qalarabbuka huwa AAalayya hayyinun waqad khalaqtuka min qablu walamtaku shay-a","juz":16,"page":305},{"s":19,"a":10,"key":"19:10","ar":"قَالَ رَبِّ ٱجْعَل لِّىٓ ءَايَةً ۚ قَالَ ءَايَتُكَ أَلَّا تُكَلِّمَ ٱلنَّاسَ ثَلَـٰثَ لَيَالٍ سَوِيًّا","en":"[Zechariah] said, \"My Lord, make for me a sign.\" He said, \"Your sign is that you will not speak to the people for three nights, [being] sound.\"1","tr":"Qala rabbi ijAAal lee ayatan qalaayatuka alla tukallima annasa thalathalayalin sawiyya","juz":16,"page":305},{"s":19,"a":11,"key":"19:11","ar":"فَخَرَجَ عَلَىٰ قَوْمِهِۦ مِنَ ٱلْمِحْرَابِ فَأَوْحَىٰٓ إِلَيْهِمْ أَن سَبِّحُوا۟ بُكْرَةً وَعَشِيًّا","en":"So he came out to his people from the prayer chamber and signaled to them to exalt [Allāh] in the morning and afternoon.","tr":"Fakharaja AAala qawmihi mina almihrabifaawha ilayhim an sabbihoo bukratan waAAashiyya","juz":16,"page":305},{"s":19,"a":12,"key":"19:12","ar":"يَـٰيَحْيَىٰ خُذِ ٱلْكِتَـٰبَ بِقُوَّةٍ ۖ وَءَاتَيْنَـٰهُ ٱلْحُكْمَ صَبِيًّا","en":"[Allāh said], \"O John, take the Scripture [i.e., adhere to it] with determination.\" And We gave him judgement [while yet] a boy","tr":"Ya yahya khuthialkitaba biquwwatin waataynahu alhukmasabiyya","juz":16,"page":306},{"s":19,"a":13,"key":"19:13","ar":"وَحَنَانًا مِّن لَّدُنَّا وَزَكَوٰةً ۖ وَكَانَ تَقِيًّا","en":"And affection from Us and purity, and he was fearing of Allāh","tr":"Wahananan min ladunnawazakatan wakana taqiyya","juz":16,"page":306},{"s":19,"a":14,"key":"19:14","ar":"وَبَرًّۢا بِوَٰلِدَيْهِ وَلَمْ يَكُن جَبَّارًا عَصِيًّا","en":"And dutiful to his parents, and he was not a disobedient tyrant.","tr":"Wabarran biwalidayhi walam yakun jabbaranAAasiyya","juz":16,"page":306},{"s":19,"a":15,"key":"19:15","ar":"وَسَلَـٰمٌ عَلَيْهِ يَوْمَ وُلِدَ وَيَوْمَ يَمُوتُ وَيَوْمَ يُبْعَثُ حَيًّا","en":"And peace be upon him the day he was born and the day he dies and the day he is raised alive.","tr":"Wasalamun AAalayhi yawma wulidawayawma yamootu wayawma yubAAathu hayya","juz":16,"page":306},{"s":19,"a":16,"key":"19:16","ar":"وَٱذْكُرْ فِى ٱلْكِتَـٰبِ مَرْيَمَ إِذِ ٱنتَبَذَتْ مِنْ أَهْلِهَا مَكَانًا شَرْقِيًّا","en":"And mention, [O Muḥammad], in the Book [the story of] Mary, when she withdrew from her family to a place toward the east.","tr":"Wathkur fee alkitabimaryama ithi intabathat min ahliha makanansharqiyya","juz":16,"page":306},{"s":19,"a":17,"key":"19:17","ar":"فَٱتَّخَذَتْ مِن دُونِهِمْ حِجَابًا فَأَرْسَلْنَآ إِلَيْهَا رُوحَنَا فَتَمَثَّلَ لَهَا بَشَرًا سَوِيًّا","en":"And she took, in seclusion from them, a screen. Then We sent to her Our Angel [i.e., Gabriel], and he represented himself to her as a well-proportioned man.","tr":"Fattakhathat min doonihim hijabanfaarsalna ilayha roohanafatamaththala laha basharan sawiyya","juz":16,"page":306},{"s":19,"a":18,"key":"19:18","ar":"قَالَتْ إِنِّىٓ أَعُوذُ بِٱلرَّحْمَـٰنِ مِنكَ إِن كُنتَ تَقِيًّا","en":"She said, \"Indeed, I seek refuge in the Most Merciful from you, [so leave me], if you should be fearing of Allāh.\"","tr":"Qalat innee aAAoothu birrahmaniminka in kunta taqiyya","juz":16,"page":306},{"s":19,"a":19,"key":"19:19","ar":"قَالَ إِنَّمَآ أَنَا۠ رَسُولُ رَبِّكِ لِأَهَبَ لَكِ غُلَـٰمًا زَكِيًّا","en":"He said, \"I am only the messenger of your Lord to give you [news of] a pure boy [i.e., son].\"","tr":"Qala innama ana rasoolurabbiki li-ahaba laki ghulaman zakiyya","juz":16,"page":306},{"s":19,"a":20,"key":"19:20","ar":"قَالَتْ أَنَّىٰ يَكُونُ لِى غُلَـٰمٌ وَلَمْ يَمْسَسْنِى بَشَرٌ وَلَمْ أَكُ بَغِيًّا","en":"She said, \"How can I have a boy while no man has touched me and I have not been unchaste?\"","tr":"Qalat anna yakoonu lee ghulamunwalam yamsasnee basharun walam aku baghiyya","juz":16,"page":306},{"s":19,"a":21,"key":"19:21","ar":"قَالَ كَذَٰلِكِ قَالَ رَبُّكِ هُوَ عَلَىَّ هَيِّنٌ ۖ وَلِنَجْعَلَهُۥٓ ءَايَةً لِّلنَّاسِ وَرَحْمَةً مِّنَّا ۚ وَكَانَ أَمْرًا مَّقْضِيًّا","en":"He said, \"Thus [it will be]; your Lord says, 'It is easy for Me, and We will make him a sign to the people and a mercy from Us. And it is a matter [already] decreed.'\"","tr":"Qala kathaliki qalarabbuki huwa AAalayya hayyinun walinajAAalahu ayatan linnasiwarahmatan minna wakana amran maqdiyya","juz":16,"page":306},{"s":19,"a":22,"key":"19:22","ar":"۞ فَحَمَلَتْهُ فَٱنتَبَذَتْ بِهِۦ مَكَانًا قَصِيًّا","en":"So she conceived him, and she withdrew with him to a remote place.","tr":"Fahamalat-hu fantabathatbihi makanan qasiyya","juz":16,"page":306},{"s":19,"a":23,"key":"19:23","ar":"فَأَجَآءَهَا ٱلْمَخَاضُ إِلَىٰ جِذْعِ ٱلنَّخْلَةِ قَالَتْ يَـٰلَيْتَنِى مِتُّ قَبْلَ هَـٰذَا وَكُنتُ نَسْيًا مَّنسِيًّا","en":"And the pains of childbirth drove her to the trunk of a palm tree. She said, \"Oh, I wish I had died before this and was in oblivion, forgotten.\"","tr":"Faajaaha almakhadu ilajithAAi annakhlati qalat ya laytaneemittu qabla hatha wakuntu nasyan mansiyya","juz":16,"page":306},{"s":19,"a":24,"key":"19:24","ar":"فَنَادَىٰهَا مِن تَحْتِهَآ أَلَّا تَحْزَنِى قَدْ جَعَلَ رَبُّكِ تَحْتَكِ سَرِيًّا","en":"But he1 called her from below her, \"Do not grieve; your Lord has provided beneath you a stream.","tr":"Fanadaha min tahtihaalla tahzanee qad jaAAala rabbuki tahtakisariyya","juz":16,"page":306},{"s":19,"a":25,"key":"19:25","ar":"وَهُزِّىٓ إِلَيْكِ بِجِذْعِ ٱلنَّخْلَةِ تُسَـٰقِطْ عَلَيْكِ رُطَبًا جَنِيًّا","en":"And shake toward you the trunk of the palm tree; it will drop upon you ripe, fresh dates.","tr":"Wahuzzee ilayki bijithAAi annakhlatitusaqit AAalayki rutaban janiyya","juz":16,"page":306},{"s":19,"a":26,"key":"19:26","ar":"فَكُلِى وَٱشْرَبِى وَقَرِّى عَيْنًا ۖ فَإِمَّا تَرَيِنَّ مِنَ ٱلْبَشَرِ أَحَدًا فَقُولِىٓ إِنِّى نَذَرْتُ لِلرَّحْمَـٰنِ صَوْمًا فَلَنْ أُكَلِّمَ ٱلْيَوْمَ إِنسِيًّا","en":"So eat and drink and be contented. And if you see from among humanity anyone, say, 'Indeed, I have vowed to the Most Merciful abstention, so I will not speak today to [any] man.'\"","tr":"Fakulee washrabee waqarree AAaynanfa-imma tarayinna mina albashari ahadan faqooleeinnee nathartu lirrahmani sawmanfalan okallima alyawma insiyya","juz":16,"page":307},{"s":19,"a":27,"key":"19:27","ar":"فَأَتَتْ بِهِۦ قَوْمَهَا تَحْمِلُهُۥ ۖ قَالُوا۟ يَـٰمَرْيَمُ لَقَدْ جِئْتِ شَيْـًٔا فَرِيًّا","en":"Then she brought him to her people, carrying him. They said, \"O Mary, you have certainly done a thing unprecedented.","tr":"Faatat bihi qawmaha tahmiluhuqaloo ya maryamu laqad ji/ti shay-an fariyya","juz":16,"page":307},{"s":19,"a":28,"key":"19:28","ar":"يَـٰٓأُخْتَ هَـٰرُونَ مَا كَانَ أَبُوكِ ٱمْرَأَ سَوْءٍ وَمَا كَانَتْ أُمُّكِ بَغِيًّا","en":"O sister [i.e., descendant] of Aaron, your father was not a man of evil, nor was your mother unchaste.\"","tr":"Ya okhta haroona ma kanaabooki imraa saw-in wama kanat ommuki baghiyya","juz":16,"page":307},{"s":19,"a":29,"key":"19:29","ar":"فَأَشَارَتْ إِلَيْهِ ۖ قَالُوا۟ كَيْفَ نُكَلِّمُ مَن كَانَ فِى ٱلْمَهْدِ صَبِيًّا","en":"So she pointed to him. They said, \"How can we speak to one who is in the cradle a child?\"","tr":"Faasharat ilayhi qaloo kayfanukallimu man kana fee almahdi sabiyya","juz":16,"page":307},{"s":19,"a":30,"key":"19:30","ar":"قَالَ إِنِّى عَبْدُ ٱللَّهِ ءَاتَىٰنِىَ ٱلْكِتَـٰبَ وَجَعَلَنِى نَبِيًّا","en":"[Jesus] said, \"Indeed, I am the servant of Allāh. He has given me the Scripture and made me a prophet.","tr":"Qala innee AAabdu Allahi ataniyaalkitaba wajaAAalanee nabiyya","juz":16,"page":307},{"s":19,"a":31,"key":"19:31","ar":"وَجَعَلَنِى مُبَارَكًا أَيْنَ مَا كُنتُ وَأَوْصَـٰنِى بِٱلصَّلَوٰةِ وَٱلزَّكَوٰةِ مَا دُمْتُ حَيًّا","en":"And He has made me blessed wherever I am and has enjoined upon me prayer and zakāh as long as I remain alive","tr":"WajaAAalanee mubarakan aynamakuntu waawsanee bissalati wazzakatima dumtu hayya","juz":16,"page":307},{"s":19,"a":32,"key":"19:32","ar":"وَبَرًّۢا بِوَٰلِدَتِى وَلَمْ يَجْعَلْنِى جَبَّارًا شَقِيًّا","en":"And [made me] dutiful to my mother, and He has not made me a wretched tyrant.","tr":"Wabarran biwalidatee walam yajAAalneejabbaran shaqiyya","juz":16,"page":307},{"s":19,"a":33,"key":"19:33","ar":"وَٱلسَّلَـٰمُ عَلَىَّ يَوْمَ وُلِدتُّ وَيَوْمَ أَمُوتُ وَيَوْمَ أُبْعَثُ حَيًّا","en":"And peace is on me the day I was born and the day I will die and the day I am raised alive.\"","tr":"Wassalamu AAalayya yawmawulidtu wayawma amootu wayawma obAAathu hayya","juz":16,"page":307},{"s":19,"a":34,"key":"19:34","ar":"ذَٰلِكَ عِيسَى ٱبْنُ مَرْيَمَ ۚ قَوْلَ ٱلْحَقِّ ٱلَّذِى فِيهِ يَمْتَرُونَ","en":"That is Jesus, the son of Mary - the word of truth about which they are in dispute.","tr":"Thalika AAeesa ibnu maryamaqawla alhaqqi allathee feehi yamtaroon","juz":16,"page":307},{"s":19,"a":35,"key":"19:35","ar":"مَا كَانَ لِلَّهِ أَن يَتَّخِذَ مِن وَلَدٍ ۖ سُبْحَـٰنَهُۥٓ ۚ إِذَا قَضَىٰٓ أَمْرًا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ","en":"It is not [befitting] for Allāh to take a son; exalted is He!1 When He decrees an affair, He only says to it, \"Be,\" and it is.","tr":"Ma kana lillahi anyattakhitha min waladin subhanahu itha qadaamran fa-innama yaqoolu lahu kun fayakoon","juz":16,"page":307},{"s":19,"a":36,"key":"19:36","ar":"وَإِنَّ ٱللَّهَ رَبِّى وَرَبُّكُمْ فَٱعْبُدُوهُ ۚ هَـٰذَا صِرَٰطٌ مُّسْتَقِيمٌ","en":"[Jesus said], \"And indeed, Allāh is my Lord and your Lord, so worship Him. That is a straight path.\"","tr":"Wa-inna Allaha rabbee warabbukum faAAbudoohuhatha siratun mustaqeem","juz":16,"page":307},{"s":19,"a":37,"key":"19:37","ar":"فَٱخْتَلَفَ ٱلْأَحْزَابُ مِنۢ بَيْنِهِمْ ۖ فَوَيْلٌ لِّلَّذِينَ كَفَرُوا۟ مِن مَّشْهَدِ يَوْمٍ عَظِيمٍ","en":"Then the factions differed [concerning Jesus] from among them, so woe to those who disbelieved - from the scene of a tremendous Day.","tr":"Fakhtalafa al-ahzabumin baynihim fawaylun lillatheena kafaroo min mashhadiyawmin AAatheem","juz":16,"page":307},{"s":19,"a":38,"key":"19:38","ar":"أَسْمِعْ بِهِمْ وَأَبْصِرْ يَوْمَ يَأْتُونَنَا ۖ لَـٰكِنِ ٱلظَّـٰلِمُونَ ٱلْيَوْمَ فِى ضَلَـٰلٍ مُّبِينٍ","en":"How [clearly] they will hear and see the Day they come to Us, but the wrongdoers today are in clear error.","tr":"AsmiAA bihim waabsir yawma ya/toonanalakini aththalimoona alyawmafee dalalin mubeen","juz":16,"page":307},{"s":19,"a":39,"key":"19:39","ar":"وَأَنذِرْهُمْ يَوْمَ ٱلْحَسْرَةِ إِذْ قُضِىَ ٱلْأَمْرُ وَهُمْ فِى غَفْلَةٍ وَهُمْ لَا يُؤْمِنُونَ","en":"And warn them, [O Muḥammad], of the Day of Regret, when the matter will be concluded;1 and [yet], they are in [a state of] heedlessness, and they do not believe.","tr":"Waanthirhum yawma alhasrati ithqudiya al-amru wahum fee ghaflatin wahum layu/minoon","juz":16,"page":308},{"s":19,"a":40,"key":"19:40","ar":"إِنَّا نَحْنُ نَرِثُ ٱلْأَرْضَ وَمَنْ عَلَيْهَا وَإِلَيْنَا يُرْجَعُونَ","en":"Indeed, it is We who will inherit the earth and whoever is on it, and to Us they will be returned.","tr":"Inna nahnu narithu al-ardawaman AAalayha wa-ilayna yurjaAAoon","juz":16,"page":308},{"s":19,"a":41,"key":"19:41","ar":"وَٱذْكُرْ فِى ٱلْكِتَـٰبِ إِبْرَٰهِيمَ ۚ إِنَّهُۥ كَانَ صِدِّيقًا نَّبِيًّا","en":"And mention in the Book [the story of] Abraham. Indeed, he was a man of truth and a prophet.","tr":"Wathkur fee alkitabiibraheema innahu kana siddeeqan nabiyya","juz":16,"page":308},{"s":19,"a":42,"key":"19:42","ar":"إِذْ قَالَ لِأَبِيهِ يَـٰٓأَبَتِ لِمَ تَعْبُدُ مَا لَا يَسْمَعُ وَلَا يُبْصِرُ وَلَا يُغْنِى عَنكَ شَيْـًٔا","en":"[Mention] when he said to his father, \"O my father, why do you worship that which does not hear and does not see and will not benefit you at all?","tr":"Ith qala li-abeehi yaabati lima taAAbudu ma la yasmaAAu wala yubsiruwala yughnee AAanka shay-a","juz":16,"page":308},{"s":19,"a":43,"key":"19:43","ar":"يَـٰٓأَبَتِ إِنِّى قَدْ جَآءَنِى مِنَ ٱلْعِلْمِ مَا لَمْ يَأْتِكَ فَٱتَّبِعْنِىٓ أَهْدِكَ صِرَٰطًا سَوِيًّا","en":"O my father, indeed there has come to me of knowledge that which has not come to you, so follow me; I will guide you to an even path.","tr":"Ya abati innee qad jaanee minaalAAilmi ma lam ya/tika fattabiAAnee ahdika siratansawiyya","juz":16,"page":308},{"s":19,"a":44,"key":"19:44","ar":"يَـٰٓأَبَتِ لَا تَعْبُدِ ٱلشَّيْطَـٰنَ ۖ إِنَّ ٱلشَّيْطَـٰنَ كَانَ لِلرَّحْمَـٰنِ عَصِيًّا","en":"O my father, do not worship [i.e., obey] Satan. Indeed Satan has ever been, to the Most Merciful, disobedient.","tr":"Ya abati la taAAbudi ashshaytanainna ashshaytana kana lirrahmaniAAasiyya","juz":16,"page":308},{"s":19,"a":45,"key":"19:45","ar":"يَـٰٓأَبَتِ إِنِّىٓ أَخَافُ أَن يَمَسَّكَ عَذَابٌ مِّنَ ٱلرَّحْمَـٰنِ فَتَكُونَ لِلشَّيْطَـٰنِ وَلِيًّا","en":"O my father, indeed I fear that there will touch you a punishment from the Most Merciful so you would be to Satan a companion [in Hellfire].\"","tr":"Ya abati innee akhafu anyamassaka AAathabun mina arrahmanifatakoona lishshyatani waliyya","juz":16,"page":308},{"s":19,"a":46,"key":"19:46","ar":"قَالَ أَرَاغِبٌ أَنتَ عَنْ ءَالِهَتِى يَـٰٓإِبْرَٰهِيمُ ۖ لَئِن لَّمْ تَنتَهِ لَأَرْجُمَنَّكَ ۖ وَٱهْجُرْنِى مَلِيًّا","en":"[His father] said, \"Have you no desire for my gods, O Abraham? If you do not desist, I will surely stone you, so avoid me a prolonged time.\"","tr":"Qala araghibun anta AAan alihateeya ibraheemu la-in lam tantahi laarjumannaka wahjurneemaliyya","juz":16,"page":308},{"s":19,"a":47,"key":"19:47","ar":"قَالَ سَلَـٰمٌ عَلَيْكَ ۖ سَأَسْتَغْفِرُ لَكَ رَبِّىٓ ۖ إِنَّهُۥ كَانَ بِى حَفِيًّا","en":"[Abraham] said, \"Peace [i.e., safety] will be upon you.1 I will ask forgiveness for you of my Lord. Indeed, He is ever gracious to me.","tr":"Qala salamun AAalaykasaastaghfiru laka rabbee innahu kana bee hafiyya","juz":16,"page":308},{"s":19,"a":48,"key":"19:48","ar":"وَأَعْتَزِلُكُمْ وَمَا تَدْعُونَ مِن دُونِ ٱللَّهِ وَأَدْعُوا۟ رَبِّى عَسَىٰٓ أَلَّآ أَكُونَ بِدُعَآءِ رَبِّى شَقِيًّا","en":"And I will leave you and those you invoke other than Allāh and will invoke1 my Lord. I expect that I will not be in invocation to my Lord unhappy [i.e., disappointed].\"","tr":"WaaAAtazilukum wama tadAAoona mindooni Allahi waadAAoo rabbee AAasa allaakoona biduAAa-i rabbee shaqiyya","juz":16,"page":308},{"s":19,"a":49,"key":"19:49","ar":"فَلَمَّا ٱعْتَزَلَهُمْ وَمَا يَعْبُدُونَ مِن دُونِ ٱللَّهِ وَهَبْنَا لَهُۥٓ إِسْحَـٰقَ وَيَعْقُوبَ ۖ وَكُلًّا جَعَلْنَا نَبِيًّا","en":"So when he had left them and those they worshipped other than Allāh, We gave him Isaac and Jacob, and each [of them] We made a prophet.","tr":"Falamma iAAtazalahum wamayaAAbudoona min dooni Allahi wahabna lahu ishaqawayaAAqooba wakullan jaAAalna nabiyya","juz":16,"page":308},{"s":19,"a":50,"key":"19:50","ar":"وَوَهَبْنَا لَهُم مِّن رَّحْمَتِنَا وَجَعَلْنَا لَهُمْ لِسَانَ صِدْقٍ عَلِيًّا","en":"And We gave them of Our mercy, and We made for them a mention [i.e., reputation] of high honor.","tr":"Wawahabna lahum min rahmatinawajaAAalna lahum lisana sidqin AAaliyya","juz":16,"page":308},{"s":19,"a":51,"key":"19:51","ar":"وَٱذْكُرْ فِى ٱلْكِتَـٰبِ مُوسَىٰٓ ۚ إِنَّهُۥ كَانَ مُخْلَصًا وَكَانَ رَسُولًا نَّبِيًّا","en":"And mention in the Book, Moses. Indeed, he was chosen, and he was a messenger and a prophet.1","tr":"Wathkur fee alkitabimoosa innahu kana mukhlasan wakanarasoolan nabiyya","juz":16,"page":308},{"s":19,"a":52,"key":"19:52","ar":"وَنَـٰدَيْنَـٰهُ مِن جَانِبِ ٱلطُّورِ ٱلْأَيْمَنِ وَقَرَّبْنَـٰهُ نَجِيًّا","en":"And We called him from the side of the mount1 at [his] right and brought him near, confiding [to him].","tr":"Wanadaynahu min janibiattoori al-aymani waqarrabnahu najiyya","juz":16,"page":309},{"s":19,"a":53,"key":"19:53","ar":"وَوَهَبْنَا لَهُۥ مِن رَّحْمَتِنَآ أَخَاهُ هَـٰرُونَ نَبِيًّا","en":"And We gave him out of Our mercy his brother Aaron as a prophet.","tr":"Wawahabna lahu min rahmatinaakhahu haroona nabiyya","juz":16,"page":309},{"s":19,"a":54,"key":"19:54","ar":"وَٱذْكُرْ فِى ٱلْكِتَـٰبِ إِسْمَـٰعِيلَ ۚ إِنَّهُۥ كَانَ صَادِقَ ٱلْوَعْدِ وَكَانَ رَسُولًا نَّبِيًّا","en":"And mention in the Book, Ishmael. Indeed, he was true to his promise, and he was a messenger and a prophet.","tr":"Wathkur fee alkitabiismaAAeela innahu kana sadiqa alwaAAdi wakanarasoolan nabiyya","juz":16,"page":309},{"s":19,"a":55,"key":"19:55","ar":"وَكَانَ يَأْمُرُ أَهْلَهُۥ بِٱلصَّلَوٰةِ وَٱلزَّكَوٰةِ وَكَانَ عِندَ رَبِّهِۦ مَرْضِيًّا","en":"And he used to enjoin on his people prayer and zakāh and was to his Lord pleasing [i.e., accepted by Him].","tr":"Wakana ya/muru ahlahu bissalatiwazzakati wakana AAinda rabbihi mardiyya","juz":16,"page":309},{"s":19,"a":56,"key":"19:56","ar":"وَٱذْكُرْ فِى ٱلْكِتَـٰبِ إِدْرِيسَ ۚ إِنَّهُۥ كَانَ صِدِّيقًا نَّبِيًّا","en":"And mention in the Book, Idrees. Indeed, he was a man of truth and a prophet.","tr":"Wathkur fee alkitabiidreesa innahu kana siddeeqan nabiyya","juz":16,"page":309},{"s":19,"a":57,"key":"19:57","ar":"وَرَفَعْنَـٰهُ مَكَانًا عَلِيًّا","en":"And We raised him to a high station.","tr":"WarafaAAnahu makanan AAaliyya","juz":16,"page":309},{"s":19,"a":58,"key":"19:58","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ أَنْعَمَ ٱللَّهُ عَلَيْهِم مِّنَ ٱلنَّبِيِّـۧنَ مِن ذُرِّيَّةِ ءَادَمَ وَمِمَّنْ حَمَلْنَا مَعَ نُوحٍ وَمِن ذُرِّيَّةِ إِبْرَٰهِيمَ وَإِسْرَٰٓءِيلَ وَمِمَّنْ هَدَيْنَا وَٱجْتَبَيْنَآ ۚ إِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَـٰتُ ٱلرَّحْمَـٰنِ خَرُّوا۟ سُجَّدًا وَبُكِيًّا ۩","en":"Those were the ones upon whom Allāh bestowed favor from among the prophets of the descendants of Adam and of those We carried [in the ship] with Noah, and of the descendants of Abraham and Israel [i.e., Jacob], and of those whom We guided and chose. When the verses of the Most Merciful were recited to them, they fell in prostration and weeping.","tr":"Ola-ika allatheena anAAama AllahuAAalayhim mina annabiyyeena min thurriyyati adamawamimman hamalna maAAa noohin wamin thurriyyatiibraheema wa-isra-eela wamimman hadayna wajtabaynaitha tutla AAalayhim ayatu arrahmanikharroo sujjadan wabukiyya","juz":16,"page":309},{"s":19,"a":59,"key":"19:59","ar":"۞ فَخَلَفَ مِنۢ بَعْدِهِمْ خَلْفٌ أَضَاعُوا۟ ٱلصَّلَوٰةَ وَٱتَّبَعُوا۟ ٱلشَّهَوَٰتِ ۖ فَسَوْفَ يَلْقَوْنَ غَيًّا","en":"But there came after them successors [i.e., later generations] who neglected prayer and pursued desires; so they are going to meet evil1 -","tr":"Fakhalafa min baAAdihim khalfun adaAAooassalata wattabaAAoo ashshahawatifasawfa yalqawna ghayya","juz":16,"page":309},{"s":19,"a":60,"key":"19:60","ar":"إِلَّا مَن تَابَ وَءَامَنَ وَعَمِلَ صَـٰلِحًا فَأُو۟لَـٰٓئِكَ يَدْخُلُونَ ٱلْجَنَّةَ وَلَا يُظْلَمُونَ شَيْـًٔا","en":"Except those who repent, believe and do righteousness; for those will enter Paradise and will not be wronged at all.","tr":"Illa man taba waamanawaAAamila salihan faola-ika yadkhuloonaaljannata wala yuthlamoona shay-a","juz":16,"page":309},{"s":19,"a":61,"key":"19:61","ar":"جَنَّـٰتِ عَدْنٍ ٱلَّتِى وَعَدَ ٱلرَّحْمَـٰنُ عِبَادَهُۥ بِٱلْغَيْبِ ۚ إِنَّهُۥ كَانَ وَعْدُهُۥ مَأْتِيًّا","en":"[Therein are] gardens of perpetual residence which the Most Merciful has promised His servants in the unseen. Indeed, His promise has ever been eminent.1","tr":"Jannati AAadnin allatee waAAada arrahmanuAAibadahu bighaybi innahu kana waAAduhuma/tiyya","juz":16,"page":309},{"s":19,"a":62,"key":"19:62","ar":"لَّا يَسْمَعُونَ فِيهَا لَغْوًا إِلَّا سَلَـٰمًا ۖ وَلَهُمْ رِزْقُهُمْ فِيهَا بُكْرَةً وَعَشِيًّا","en":"They will not hear therein any ill speech - only [greetings of] peace - and they will have their provision therein, morning and afternoon.","tr":"La yasmaAAoona feeha laghwanilla salaman walahum rizquhum feeha bukratanwaAAashiyya","juz":16,"page":309},{"s":19,"a":63,"key":"19:63","ar":"تِلْكَ ٱلْجَنَّةُ ٱلَّتِى نُورِثُ مِنْ عِبَادِنَا مَن كَانَ تَقِيًّا","en":"That is Paradise, which We give as inheritance to those of Our servants who were fearing of Allāh.","tr":"Tilka aljannatu allatee noorithu min AAibadinaman kana taqiyya","juz":16,"page":309},{"s":19,"a":64,"key":"19:64","ar":"وَمَا نَتَنَزَّلُ إِلَّا بِأَمْرِ رَبِّكَ ۖ لَهُۥ مَا بَيْنَ أَيْدِينَا وَمَا خَلْفَنَا وَمَا بَيْنَ ذَٰلِكَ ۚ وَمَا كَانَ رَبُّكَ نَسِيًّا","en":"[Gabriel said],1 \"And we [angels] descend not except by the order of your Lord. To Him belongs that before us and that behind us and what is in between. And never is your Lord forgetful -","tr":"Wama natanazzalu illa bi-amrirabbika lahu ma bayna aydeena wama khalfanawama bayna thalika wama kana rabbukanasiyya","juz":16,"page":309},{"s":19,"a":65,"key":"19:65","ar":"رَّبُّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا فَٱعْبُدْهُ وَٱصْطَبِرْ لِعِبَـٰدَتِهِۦ ۚ هَلْ تَعْلَمُ لَهُۥ سَمِيًّا","en":"Lord of the heavens and the earth and whatever is between them - so worship Him and have patience for His worship. Do you know of any similarity to Him?\"","tr":"Rabbu assamawati wal-ardiwama baynahuma faAAbudhu wastabirliAAibadatihi hal taAAlamu lahu samiyya","juz":16,"page":310},{"s":19,"a":66,"key":"19:66","ar":"وَيَقُولُ ٱلْإِنسَـٰنُ أَءِذَا مَا مِتُّ لَسَوْفَ أُخْرَجُ حَيًّا","en":"And man [i.e., the disbeliever] says, \"When I have died, am I going to be brought forth alive?\"","tr":"Wayaqoolu al-insanu a-itha mamittu lasawfa okhraju hayya","juz":16,"page":310},{"s":19,"a":67,"key":"19:67","ar":"أَوَلَا يَذْكُرُ ٱلْإِنسَـٰنُ أَنَّا خَلَقْنَـٰهُ مِن قَبْلُ وَلَمْ يَكُ شَيْـًٔا","en":"Does man not remember that We created him before, while he was nothing?","tr":"Awa la yathkuru al-insanuanna khalaqnahu min qablu walam yaku shay-a","juz":16,"page":310},{"s":19,"a":68,"key":"19:68","ar":"فَوَرَبِّكَ لَنَحْشُرَنَّهُمْ وَٱلشَّيَـٰطِينَ ثُمَّ لَنُحْضِرَنَّهُمْ حَوْلَ جَهَنَّمَ جِثِيًّا","en":"So by your Lord, We will surely gather them and the devils; then We will bring them to be present around Hell upon their knees.1","tr":"Fawarabbika lanahshurannahum washshayateenathumma lanuhdirannahum hawla jahannama jithiyya","juz":16,"page":310},{"s":19,"a":69,"key":"19:69","ar":"ثُمَّ لَنَنزِعَنَّ مِن كُلِّ شِيعَةٍ أَيُّهُمْ أَشَدُّ عَلَى ٱلرَّحْمَـٰنِ عِتِيًّا","en":"Then We will surely extract from every sect those of them who were worst against the Most Merciful in insolence.","tr":"Thumma lananziAAanna min kulli sheeAAatinayyuhum ashaddu AAala arrahmaniAAitiyya","juz":16,"page":310},{"s":19,"a":70,"key":"19:70","ar":"ثُمَّ لَنَحْنُ أَعْلَمُ بِٱلَّذِينَ هُمْ أَوْلَىٰ بِهَا صِلِيًّا","en":"Then, surely it is We who are most knowing of those most worthy of burning therein.","tr":"Thumma lanahnu aAAlamu billatheenahum awla biha siliyya","juz":16,"page":310},{"s":19,"a":71,"key":"19:71","ar":"وَإِن مِّنكُمْ إِلَّا وَارِدُهَا ۚ كَانَ عَلَىٰ رَبِّكَ حَتْمًا مَّقْضِيًّا","en":"And there is none of you except he will come to it.1 This is upon your Lord an inevitability decreed.","tr":"Wa-in minkum illa wariduhakana AAala rabbika hatman maqdiyya","juz":16,"page":310},{"s":19,"a":72,"key":"19:72","ar":"ثُمَّ نُنَجِّى ٱلَّذِينَ ٱتَّقَوا۟ وَّنَذَرُ ٱلظَّـٰلِمِينَ فِيهَا جِثِيًّا","en":"Then We will save those who feared Allāh and leave the wrongdoers within it, on their knees.","tr":"Thumma nunajjee allatheena ittaqawwanatharu aththalimeena feehajithiyya","juz":16,"page":310},{"s":19,"a":73,"key":"19:73","ar":"وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَـٰتُنَا بَيِّنَـٰتٍ قَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوٓا۟ أَىُّ ٱلْفَرِيقَيْنِ خَيْرٌ مَّقَامًا وَأَحْسَنُ نَدِيًّا","en":"And when Our verses are recited to them as clear evidences, those who disbelieve say to those who believe, \"Which of [our] two parties is best in position and best in association?\"1","tr":"Wa-itha tutla AAalayhim ayatunabayyinatin qala allatheena kafaroo lillatheenaamanoo ayyu alfareeqayni khayrun maqaman waahsanunadiyya","juz":16,"page":310},{"s":19,"a":74,"key":"19:74","ar":"وَكَمْ أَهْلَكْنَا قَبْلَهُم مِّن قَرْنٍ هُمْ أَحْسَنُ أَثَـٰثًا وَرِءْيًا","en":"And how many a generation have We destroyed before them who were better in possessions and [outward] appearance?","tr":"Wakam ahlakna qablahum min qarnin humahsanu athathan wari/ya","juz":16,"page":310},{"s":19,"a":75,"key":"19:75","ar":"قُلْ مَن كَانَ فِى ٱلضَّلَـٰلَةِ فَلْيَمْدُدْ لَهُ ٱلرَّحْمَـٰنُ مَدًّا ۚ حَتَّىٰٓ إِذَا رَأَوْا۟ مَا يُوعَدُونَ إِمَّا ٱلْعَذَابَ وَإِمَّا ٱلسَّاعَةَ فَسَيَعْلَمُونَ مَنْ هُوَ شَرٌّ مَّكَانًا وَأَضْعَفُ جُندًا","en":"Say, \"Whoever is in error - let the Most Merciful extend for him an extension [in wealth and time] until, when they see that which they were promised - either punishment [in this world] or the Hour [of resurrection] - they will come to know who is worst in position and weaker in soldiers.\"","tr":"Qul man kana fee addalalatifalyamdud lahu arrahmanu maddan hattaitha raaw ma yooAAadoona imma alAAathabawa-imma assaAAata fasayaAAlamoona man huwasharrun makanan waadAAafu junda","juz":16,"page":310},{"s":19,"a":76,"key":"19:76","ar":"وَيَزِيدُ ٱللَّهُ ٱلَّذِينَ ٱهْتَدَوْا۟ هُدًى ۗ وَٱلْبَـٰقِيَـٰتُ ٱلصَّـٰلِحَـٰتُ خَيْرٌ عِندَ رَبِّكَ ثَوَابًا وَخَيْرٌ مَّرَدًّا","en":"And Allāh increases those who were guided, in guidance, and the enduring good deeds are better to your Lord1 for reward and better for recourse.","tr":"Wayazeedu Allahu allatheenaihtadaw hudan walbaqiyatu assalihatukhayrun AAinda rabbika thawaban wakhayrun maradda","juz":16,"page":310},{"s":19,"a":77,"key":"19:77","ar":"أَفَرَءَيْتَ ٱلَّذِى كَفَرَ بِـَٔايَـٰتِنَا وَقَالَ لَأُوتَيَنَّ مَالًا وَوَلَدًا","en":"Then, have you seen he who disbelieved in Our verses and said, \"I will surely be given wealth and children [in the next life]\"?","tr":"Afaraayta allathee kafara bi-ayatinawaqala laootayanna malan wawalada","juz":16,"page":311},{"s":19,"a":78,"key":"19:78","ar":"أَطَّلَعَ ٱلْغَيْبَ أَمِ ٱتَّخَذَ عِندَ ٱلرَّحْمَـٰنِ عَهْدًا","en":"Has he looked into the unseen, or has he taken from the Most Merciful a promise?","tr":"AttalaAAa alghayba ami ittakhathaAAinda arrahmani AAahda","juz":16,"page":311},{"s":19,"a":79,"key":"19:79","ar":"كَلَّا ۚ سَنَكْتُبُ مَا يَقُولُ وَنَمُدُّ لَهُۥ مِنَ ٱلْعَذَابِ مَدًّا","en":"No! We will record what he says and extend [i.e., increase] for him from the punishment extensively.","tr":"Kalla sanaktubu ma yaqooluwanamuddu lahu mina alAAathabi madda","juz":16,"page":311},{"s":19,"a":80,"key":"19:80","ar":"وَنَرِثُهُۥ مَا يَقُولُ وَيَأْتِينَا فَرْدًا","en":"And We will inherit him [in] what he mentions,1 and he will come to Us alone.","tr":"Wanarithuhu ma yaqoolu waya/teenafarda","juz":16,"page":311},{"s":19,"a":81,"key":"19:81","ar":"وَٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ ءَالِهَةً لِّيَكُونُوا۟ لَهُمْ عِزًّا","en":"And they have taken besides Allāh [false] deities that they would be for them [a source of] honor.","tr":"Wattakhathoo min dooni Allahialihatan liyakoonoo lahum AAizza","juz":16,"page":311},{"s":19,"a":82,"key":"19:82","ar":"كَلَّا ۚ سَيَكْفُرُونَ بِعِبَادَتِهِمْ وَيَكُونُونَ عَلَيْهِمْ ضِدًّا","en":"No! They [i.e., those \"gods\"] will deny their worship of them and will be against them opponents [on the Day of Judgement].","tr":"Kalla sayakfuroona biAAibadatihimwayakoonoona AAalayhim didda","juz":16,"page":311},{"s":19,"a":83,"key":"19:83","ar":"أَلَمْ تَرَ أَنَّآ أَرْسَلْنَا ٱلشَّيَـٰطِينَ عَلَى ٱلْكَـٰفِرِينَ تَؤُزُّهُمْ أَزًّا","en":"Do you not see that We have sent the devils upon the disbelievers, inciting them [to evil] with [constant] incitement?","tr":"Alam tara anna arsalna ashshayateenaAAala alkafireena taozzuhum azza","juz":16,"page":311},{"s":19,"a":84,"key":"19:84","ar":"فَلَا تَعْجَلْ عَلَيْهِمْ ۖ إِنَّمَا نَعُدُّ لَهُمْ عَدًّا","en":"So be not impatient over them. We only count out [i.e., allow] to them a [limited] number.1","tr":"Fala taAAjal AAalayhim innamanaAAuddu lahum AAadda","juz":16,"page":311},{"s":19,"a":85,"key":"19:85","ar":"يَوْمَ نَحْشُرُ ٱلْمُتَّقِينَ إِلَى ٱلرَّحْمَـٰنِ وَفْدًا","en":"On the Day We will gather the righteous to the Most Merciful as a delegation","tr":"Yawma nahshuru almuttaqeena ilaarrahmani wafda","juz":16,"page":311},{"s":19,"a":86,"key":"19:86","ar":"وَنَسُوقُ ٱلْمُجْرِمِينَ إِلَىٰ جَهَنَّمَ وِرْدًا","en":"And will drive the criminals to Hell in thirst","tr":"Wanasooqu almujrimeena ila jahannamawirda","juz":16,"page":311},{"s":19,"a":87,"key":"19:87","ar":"لَّا يَمْلِكُونَ ٱلشَّفَـٰعَةَ إِلَّا مَنِ ٱتَّخَذَ عِندَ ٱلرَّحْمَـٰنِ عَهْدًا","en":"None will have [power of] intercession except he who had taken from the Most Merciful a covenant.1","tr":"La yamlikoona ashshafaAAatailla mani ittakhatha AAinda arrahmaniAAahda","juz":16,"page":311},{"s":19,"a":88,"key":"19:88","ar":"وَقَالُوا۟ ٱتَّخَذَ ٱلرَّحْمَـٰنُ وَلَدًا","en":"And they say, \"The Most Merciful has taken [for Himself] a son.\"","tr":"Waqaloo ittakhatha arrahmanuwalada","juz":16,"page":311},{"s":19,"a":89,"key":"19:89","ar":"لَّقَدْ جِئْتُمْ شَيْـًٔا إِدًّا","en":"You have done an atrocious thing.","tr":"Laqad ji/tum shay-an idda","juz":16,"page":311},{"s":19,"a":90,"key":"19:90","ar":"تَكَادُ ٱلسَّمَـٰوَٰتُ يَتَفَطَّرْنَ مِنْهُ وَتَنشَقُّ ٱلْأَرْضُ وَتَخِرُّ ٱلْجِبَالُ هَدًّا","en":"The heavens almost rupture therefrom and the earth splits open and the mountains collapse in devastation","tr":"Takadu assamawatuyatafattarna minhu watanshaqqu al-ardu watakhirrualjibalu hadda","juz":16,"page":311},{"s":19,"a":91,"key":"19:91","ar":"أَن دَعَوْا۟ لِلرَّحْمَـٰنِ وَلَدًا","en":"That they attribute to the Most Merciful a son.","tr":"An daAAaw lirrahmaniwalada","juz":16,"page":311},{"s":19,"a":92,"key":"19:92","ar":"وَمَا يَنۢبَغِى لِلرَّحْمَـٰنِ أَن يَتَّخِذَ وَلَدًا","en":"And it is not appropriate for the Most Merciful that He should take a son.","tr":"Wama yanbaghee lirrahmanian yattakhitha walada","juz":16,"page":311},{"s":19,"a":93,"key":"19:93","ar":"إِن كُلُّ مَن فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ إِلَّآ ءَاتِى ٱلرَّحْمَـٰنِ عَبْدًا","en":"There is no one in the heavens and earth but that he comes to the Most Merciful as a servant.","tr":"In kullu man fee assamawatiwal-ardi illa atee arrahmaniAAabda","juz":16,"page":311},{"s":19,"a":94,"key":"19:94","ar":"لَّقَدْ أَحْصَىٰهُمْ وَعَدَّهُمْ عَدًّا","en":"He has enumerated them and counted them a [full] counting.","tr":"Laqad ahsahum waAAaddahum AAadda","juz":16,"page":311},{"s":19,"a":95,"key":"19:95","ar":"وَكُلُّهُمْ ءَاتِيهِ يَوْمَ ٱلْقِيَـٰمَةِ فَرْدًا","en":"And all of them are coming to Him on the Day of Resurrection alone.","tr":"Wakulluhum ateehi yawma alqiyamatifarda","juz":16,"page":311},{"s":19,"a":96,"key":"19:96","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ سَيَجْعَلُ لَهُمُ ٱلرَّحْمَـٰنُ وُدًّا","en":"Indeed, those who have believed and done righteous deeds - the Most Merciful will appoint for them affection.1","tr":"Inna allatheena amanoowaAAamiloo assalihati sayajAAalu lahumu arrahmanuwudda","juz":16,"page":312},{"s":19,"a":97,"key":"19:97","ar":"فَإِنَّمَا يَسَّرْنَـٰهُ بِلِسَانِكَ لِتُبَشِّرَ بِهِ ٱلْمُتَّقِينَ وَتُنذِرَ بِهِۦ قَوْمًا لُّدًّا","en":"So, [O Muḥammad], We have only made it [i.e., the Qur’ān] easy in your tongue [i.e., the Arabic language] that you may give good tidings thereby to the righteous and warn thereby a hostile people.","tr":"Fa-innama yassarnahu bilisanikalitubashshira bihi almuttaqeena watunthira bihi qawmanludda","juz":16,"page":312},{"s":19,"a":98,"key":"19:98","ar":"وَكَمْ أَهْلَكْنَا قَبْلَهُم مِّن قَرْنٍ هَلْ تُحِسُّ مِنْهُم مِّنْ أَحَدٍ أَوْ تَسْمَعُ لَهُمْ رِكْزًۢا","en":"And how many have We destroyed before them of generations? Do you perceive of them anyone or hear from them a sound?","tr":"Wakam ahlakna qablahum min qarnin haltuhissu minhum min ahadin aw tasmaAAu lahum rikza","juz":16,"page":312},{"s":20,"a":1,"key":"20:1","ar":" طه","en":"Ṭā, Hā.1","tr":"Ta-ha","juz":16,"page":312},{"s":20,"a":2,"key":"20:2","ar":"مَآ أَنزَلْنَا عَلَيْكَ ٱلْقُرْءَانَ لِتَشْقَىٰٓ","en":"We have not sent down to you the Qur’ān that you be distressed","tr":"Ma anzalna AAalayka alqur-analitashqa","juz":16,"page":312},{"s":20,"a":3,"key":"20:3","ar":"إِلَّا تَذْكِرَةً لِّمَن يَخْشَىٰ","en":"But only as a reminder for those who fear [Allāh] -","tr":"Illa tathkiratan liman yakhsha","juz":16,"page":312},{"s":20,"a":4,"key":"20:4","ar":"تَنزِيلًا مِّمَّنْ خَلَقَ ٱلْأَرْضَ وَٱلسَّمَـٰوَٰتِ ٱلْعُلَى","en":"A revelation from He who created the earth and highest heavens,","tr":"Tanzeelan mimman khalaqa al-arda wassamawatialAAula","juz":16,"page":312},{"s":20,"a":5,"key":"20:5","ar":"ٱلرَّحْمَـٰنُ عَلَى ٱلْعَرْشِ ٱسْتَوَىٰ","en":"The Most Merciful [who is] above the Throne established.1","tr":"Arrahmanu AAalaalAAarshi istawa","juz":16,"page":312},{"s":20,"a":6,"key":"20:6","ar":"لَهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ وَمَا بَيْنَهُمَا وَمَا تَحْتَ ٱلثَّرَىٰ","en":"To Him belongs what is in the heavens and what is on the earth and what is between them and what is under the soil.","tr":"Lahu ma fee assamawatiwama fee al-ardi wama baynahuma wamatahta aththara","juz":16,"page":312},{"s":20,"a":7,"key":"20:7","ar":"وَإِن تَجْهَرْ بِٱلْقَوْلِ فَإِنَّهُۥ يَعْلَمُ ٱلسِّرَّ وَأَخْفَى","en":"And if you speak aloud - then indeed, He knows the secret and what is [even] more hidden.","tr":"Wa-in tajhar bilqawli fa-innahuyaAAlamu assirra waakhfa","juz":16,"page":312},{"s":20,"a":8,"key":"20:8","ar":"ٱللَّهُ لَآ إِلَـٰهَ إِلَّا هُوَ ۖ لَهُ ٱلْأَسْمَآءُ ٱلْحُسْنَىٰ","en":"Allāh - there is no deity except Him. To Him belong the best names.","tr":"Allahu la ilaha illahuwa lahu al-asmao alhusna","juz":16,"page":312},{"s":20,"a":9,"key":"20:9","ar":"وَهَلْ أَتَىٰكَ حَدِيثُ مُوسَىٰٓ","en":"And has the story of Moses reached you? -","tr":"Wahal ataka hadeethu moosa","juz":16,"page":312},{"s":20,"a":10,"key":"20:10","ar":"إِذْ رَءَا نَارًا فَقَالَ لِأَهْلِهِ ٱمْكُثُوٓا۟ إِنِّىٓ ءَانَسْتُ نَارًا لَّعَلِّىٓ ءَاتِيكُم مِّنْهَا بِقَبَسٍ أَوْ أَجِدُ عَلَى ٱلنَّارِ هُدًى","en":"When he saw a fire and said to his family, \"Stay here; indeed, I have perceived a fire; perhaps I can bring you a torch or find at the fire some guidance.\"","tr":"Ith raa naran faqalali-ahlihi omkuthoo innee anastu naran laAAallee ateekumminha biqabasin aw ajidu AAala annarihuda","juz":16,"page":312},{"s":20,"a":11,"key":"20:11","ar":"فَلَمَّآ أَتَىٰهَا نُودِىَ يَـٰمُوسَىٰٓ","en":"And when he came to it, he was called, \"O Moses,","tr":"Falamma ataha noodiya yamoosa","juz":16,"page":312},{"s":20,"a":12,"key":"20:12","ar":"إِنِّىٓ أَنَا۠ رَبُّكَ فَٱخْلَعْ نَعْلَيْكَ ۖ إِنَّكَ بِٱلْوَادِ ٱلْمُقَدَّسِ طُوًى","en":"Indeed, I am your Lord, so remove your sandals. Indeed, you are in the blessed valley of Ṭuwā.","tr":"Innee ana rabbuka fakhlaAAnaAAlayka innaka bilwadi almuqaddasi tuwa","juz":16,"page":312},{"s":20,"a":13,"key":"20:13","ar":"وَأَنَا ٱخْتَرْتُكَ فَٱسْتَمِعْ لِمَا يُوحَىٰٓ","en":"And I have chosen you, so listen to what is revealed [to you].","tr":"Waana ikhtartuka fastamiAAlima yooha","juz":16,"page":313},{"s":20,"a":14,"key":"20:14","ar":"إِنَّنِىٓ أَنَا ٱللَّهُ لَآ إِلَـٰهَ إِلَّآ أَنَا۠ فَٱعْبُدْنِى وَأَقِمِ ٱلصَّلَوٰةَ لِذِكْرِىٓ","en":"Indeed, I am Allāh. There is no deity except Me, so worship Me and establish prayer for My remembrance.","tr":"Innanee ana Allahu lailaha illa ana faAAbudnee waaqimi assalatalithikree","juz":16,"page":313},{"s":20,"a":15,"key":"20:15","ar":"إِنَّ ٱلسَّاعَةَ ءَاتِيَةٌ أَكَادُ أُخْفِيهَا لِتُجْزَىٰ كُلُّ نَفْسٍۭ بِمَا تَسْعَىٰ","en":"Indeed, the Hour is coming - I almost conceal it1 - so that every soul may be recompensed according to that for which it strives.","tr":"Inna assaAAata atiyatunakadu okhfeeha litujza kullu nafsin bimatasAAa","juz":16,"page":313},{"s":20,"a":16,"key":"20:16","ar":"فَلَا يَصُدَّنَّكَ عَنْهَا مَن لَّا يُؤْمِنُ بِهَا وَٱتَّبَعَ هَوَىٰهُ فَتَرْدَىٰ","en":"So do not let one avert you from it1 who does not believe in it and follows his desire, for you [then] would perish.","tr":"Fala yasuddannaka AAanhaman la yu/minu biha wattabaAAa hawahufatarda","juz":16,"page":313},{"s":20,"a":17,"key":"20:17","ar":"وَمَا تِلْكَ بِيَمِينِكَ يَـٰمُوسَىٰ","en":"And what is that in your right hand, O Moses?\"","tr":"Wama tilka biyameenika ya moosa","juz":16,"page":313},{"s":20,"a":18,"key":"20:18","ar":"قَالَ هِىَ عَصَاىَ أَتَوَكَّؤُا۟ عَلَيْهَا وَأَهُشُّ بِهَا عَلَىٰ غَنَمِى وَلِىَ فِيهَا مَـَٔارِبُ أُخْرَىٰ","en":"He said, \"It is my staff; I lean upon it, and I bring down leaves for my sheep and I have therein other uses.\"","tr":"Qala hiya AAasaya atawakkaoAAalayha waahushshu biha AAala ghanameewaliya feeha maaribu okhra","juz":16,"page":313},{"s":20,"a":19,"key":"20:19","ar":"قَالَ أَلْقِهَا يَـٰمُوسَىٰ","en":"[Allāh] said, \"Throw it down, O Moses.\"","tr":"Qala alqiha ya moosa","juz":16,"page":313},{"s":20,"a":20,"key":"20:20","ar":"فَأَلْقَىٰهَا فَإِذَا هِىَ حَيَّةٌ تَسْعَىٰ","en":"So he threw it down, and thereupon it was a snake, moving swiftly.","tr":"Faalqaha fa-itha hiya hayyatuntasAAa","juz":16,"page":313},{"s":20,"a":21,"key":"20:21","ar":"قَالَ خُذْهَا وَلَا تَخَفْ ۖ سَنُعِيدُهَا سِيرَتَهَا ٱلْأُولَىٰ","en":"[Allāh] said, \"Seize it and fear not; We will return it to its former condition.","tr":"Qala khuthha walatakhaf sanuAAeeduha seerataha al-oola","juz":16,"page":313},{"s":20,"a":22,"key":"20:22","ar":"وَٱضْمُمْ يَدَكَ إِلَىٰ جَنَاحِكَ تَخْرُجْ بَيْضَآءَ مِنْ غَيْرِ سُوٓءٍ ءَايَةً أُخْرَىٰ","en":"And draw in your hand to your side; it will come out white without disease - another sign,","tr":"Wadmum yadaka ila janahikatakhruj baydaa min ghayri soo-in ayatan okhra","juz":16,"page":313},{"s":20,"a":23,"key":"20:23","ar":"لِنُرِيَكَ مِنْ ءَايَـٰتِنَا ٱلْكُبْرَى","en":"That We may show you [some] of Our greater signs.","tr":"Linuriyaka min ayatinaalkubra","juz":16,"page":313},{"s":20,"a":24,"key":"20:24","ar":"ٱذْهَبْ إِلَىٰ فِرْعَوْنَ إِنَّهُۥ طَغَىٰ","en":"Go to Pharaoh. Indeed, he has transgressed [i.e., tyrannized].\"","tr":"Ithhab ila firAAawna innahu tagha","juz":16,"page":313},{"s":20,"a":25,"key":"20:25","ar":"قَالَ رَبِّ ٱشْرَحْ لِى صَدْرِى","en":"[Moses] said, \"My Lord, expand [i.e., relax] for me my breast [with assurance]","tr":"Qala rabbi ishrah lee sadree","juz":16,"page":313},{"s":20,"a":26,"key":"20:26","ar":"وَيَسِّرْ لِىٓ أَمْرِى","en":"And ease for me my task","tr":"Wayassir lee amree","juz":16,"page":313},{"s":20,"a":27,"key":"20:27","ar":"وَٱحْلُلْ عُقْدَةً مِّن لِّسَانِى","en":"And untie the knot from my tongue","tr":"Wahlul AAuqdatan min lisanee","juz":16,"page":313},{"s":20,"a":28,"key":"20:28","ar":"يَفْقَهُوا۟ قَوْلِى","en":"That they may understand my speech.","tr":"Yafqahoo qawlee","juz":16,"page":313},{"s":20,"a":29,"key":"20:29","ar":"وَٱجْعَل لِّى وَزِيرًا مِّنْ أَهْلِى","en":"And appoint for me a minister [i.e., assistant] from my family -","tr":"WajAAal lee wazeeran min ahlee","juz":16,"page":313},{"s":20,"a":30,"key":"20:30","ar":"هَـٰرُونَ أَخِى","en":"Aaron, my brother.","tr":"Haroona akhee","juz":16,"page":313},{"s":20,"a":31,"key":"20:31","ar":"ٱشْدُدْ بِهِۦٓ أَزْرِى","en":"Increase through him my strength","tr":"Oshdud bihi azree","juz":16,"page":313},{"s":20,"a":32,"key":"20:32","ar":"وَأَشْرِكْهُ فِىٓ أَمْرِى","en":"And let him share my task","tr":"Waashrik-hu fee amree","juz":16,"page":313},{"s":20,"a":33,"key":"20:33","ar":"كَىْ نُسَبِّحَكَ كَثِيرًا","en":"That we may exalt You much","tr":"Kay nusabbihaka katheera","juz":16,"page":313},{"s":20,"a":34,"key":"20:34","ar":"وَنَذْكُرَكَ كَثِيرًا","en":"And remember You much.","tr":"Wanathkuraka katheera","juz":16,"page":313},{"s":20,"a":35,"key":"20:35","ar":"إِنَّكَ كُنتَ بِنَا بَصِيرًا","en":"Indeed, You are of us ever Seeing.\"","tr":"Innaka kunta bina baseera","juz":16,"page":313},{"s":20,"a":36,"key":"20:36","ar":"قَالَ قَدْ أُوتِيتَ سُؤْلَكَ يَـٰمُوسَىٰ","en":"[Allāh] said, \"You have been granted your request, O Moses.","tr":"Qala qad ooteeta su/laka yamoosa","juz":16,"page":313},{"s":20,"a":37,"key":"20:37","ar":"وَلَقَدْ مَنَنَّا عَلَيْكَ مَرَّةً أُخْرَىٰٓ","en":"And We had already conferred favor upon you another time,","tr":"Walaqad mananna AAalayka marratanokhra","juz":16,"page":313},{"s":20,"a":38,"key":"20:38","ar":"إِذْ أَوْحَيْنَآ إِلَىٰٓ أُمِّكَ مَا يُوحَىٰٓ","en":"When We inspired to your mother what We inspired,","tr":"Ith awhayna ilaommika ma yooha","juz":16,"page":314},{"s":20,"a":39,"key":"20:39","ar":"أَنِ ٱقْذِفِيهِ فِى ٱلتَّابُوتِ فَٱقْذِفِيهِ فِى ٱلْيَمِّ فَلْيُلْقِهِ ٱلْيَمُّ بِٱلسَّاحِلِ يَأْخُذْهُ عَدُوٌّ لِّى وَعَدُوٌّ لَّهُۥ ۚ وَأَلْقَيْتُ عَلَيْكَ مَحَبَّةً مِّنِّى وَلِتُصْنَعَ عَلَىٰ عَيْنِىٓ","en":"[Saying], 'Cast him into the chest and cast it into the river, and the river will throw it onto the bank; there will take him an enemy to Me and an enemy to him.' And I bestowed upon you love from Me1 that you would be brought up under My eye [i.e., observation and care].","tr":"Ani iqthifeehi fee attabootifaqthifeehi fee alyammi falyulqihi alyammu bissahiliya/khuthhu AAaduwwun lee waAAaduwwun lahu waalqaytuAAalayka mahabbatan minnee walitusnaAAa AAalaAAaynee","juz":16,"page":314},{"s":20,"a":40,"key":"20:40","ar":"إِذْ تَمْشِىٓ أُخْتُكَ فَتَقُولُ هَلْ أَدُلُّكُمْ عَلَىٰ مَن يَكْفُلُهُۥ ۖ فَرَجَعْنَـٰكَ إِلَىٰٓ أُمِّكَ كَىْ تَقَرَّ عَيْنُهَا وَلَا تَحْزَنَ ۚ وَقَتَلْتَ نَفْسًا فَنَجَّيْنَـٰكَ مِنَ ٱلْغَمِّ وَفَتَنَّـٰكَ فُتُونًا ۚ فَلَبِثْتَ سِنِينَ فِىٓ أَهْلِ مَدْيَنَ ثُمَّ جِئْتَ عَلَىٰ قَدَرٍ يَـٰمُوسَىٰ","en":"[And We favored you] when your sister went and said, 'Shall I direct you to someone who will be responsible for him?' So We restored you to your mother that she might be content and not grieve. And you killed someone,1 but We saved you from retaliation and tried you with a [severe] trial. And you remained [some] years among the people of Madyan. Then you came [here] at the decreed time, O Moses.","tr":"Ith tamshee okhtuka fataqoolu haladullukum AAala man yakfuluhu farajaAAnaka ilaommika kay taqarra AAaynuha wala tahzanawaqatalta nafsan fanajjaynaka mina alghammi wafatannakafutoonan falabithta sineena fee ahli madyana thumma ji/ta AAalaqadarin ya moosa","juz":16,"page":314},{"s":20,"a":41,"key":"20:41","ar":"وَٱصْطَنَعْتُكَ لِنَفْسِى","en":"And I produced you for Myself.1","tr":"WastanaAAtuka linafsee","juz":16,"page":314},{"s":20,"a":42,"key":"20:42","ar":"ٱذْهَبْ أَنتَ وَأَخُوكَ بِـَٔايَـٰتِى وَلَا تَنِيَا فِى ذِكْرِى","en":"Go, you and your brother, with My signs and do not slacken in My remembrance.","tr":"Ithhab anta waakhooka bi-ayateewala taniya fee thikree","juz":16,"page":314},{"s":20,"a":43,"key":"20:43","ar":"ٱذْهَبَآ إِلَىٰ فِرْعَوْنَ إِنَّهُۥ طَغَىٰ","en":"Go, both of you, to Pharaoh. Indeed, he has transgressed.","tr":"Ithhaba ila firAAawnainnahu tagha","juz":16,"page":314},{"s":20,"a":44,"key":"20:44","ar":"فَقُولَا لَهُۥ قَوْلًا لَّيِّنًا لَّعَلَّهُۥ يَتَذَكَّرُ أَوْ يَخْشَىٰ","en":"And speak to him with gentle speech that perhaps he may be reminded or fear [Allāh].\"","tr":"Faqoola lahu qawlan layyinanlaAAallahu yatathakkaru aw yakhsha","juz":16,"page":314},{"s":20,"a":45,"key":"20:45","ar":"قَالَا رَبَّنَآ إِنَّنَا نَخَافُ أَن يَفْرُطَ عَلَيْنَآ أَوْ أَن يَطْغَىٰ","en":"They said, \"Our Lord, indeed we are afraid that he will hasten [punishment] against us or that he will transgress.\"","tr":"Qala rabbana innananakhafu an yafruta AAalayna aw an yatgha","juz":16,"page":314},{"s":20,"a":46,"key":"20:46","ar":"قَالَ لَا تَخَافَآ ۖ إِنَّنِى مَعَكُمَآ أَسْمَعُ وَأَرَىٰ","en":"[Allāh] said, \"Fear not. Indeed, I am with you both; I hear and I see.","tr":"Qala la takhafainnanee maAAakuma asmaAAu waara","juz":16,"page":314},{"s":20,"a":47,"key":"20:47","ar":"فَأْتِيَاهُ فَقُولَآ إِنَّا رَسُولَا رَبِّكَ فَأَرْسِلْ مَعَنَا بَنِىٓ إِسْرَٰٓءِيلَ وَلَا تُعَذِّبْهُمْ ۖ قَدْ جِئْنَـٰكَ بِـَٔايَةٍ مِّن رَّبِّكَ ۖ وَٱلسَّلَـٰمُ عَلَىٰ مَنِ ٱتَّبَعَ ٱلْهُدَىٰٓ","en":"So go to him and say, 'Indeed, we are messengers of your Lord, so send with us the Children of Israel and do not torment them. We have come to you with a sign from your Lord. And peace1 will be upon he who follows the guidance.","tr":"Fa/tiyahu faqoola innarasoola rabbika faarsil maAAana banee isra-eelawala tuAAaththibhum qad ji/naka bi-ayatinmin rabbika wassalamu AAala mani ittabaAAaalhuda","juz":16,"page":314},{"s":20,"a":48,"key":"20:48","ar":"إِنَّا قَدْ أُوحِىَ إِلَيْنَآ أَنَّ ٱلْعَذَابَ عَلَىٰ مَن كَذَّبَ وَتَوَلَّىٰ","en":"Indeed, it has been revealed to us that the punishment will be upon whoever denies and turns away.'\"","tr":"Inna qad oohiya ilaynaanna alAAathaba AAala man kaththaba watawalla","juz":16,"page":314},{"s":20,"a":49,"key":"20:49","ar":"قَالَ فَمَن رَّبُّكُمَا يَـٰمُوسَىٰ","en":"[Pharaoh] said, \"So who is the Lord of you two, O Moses?\"","tr":"Qala faman rabbukuma yamoosa","juz":16,"page":314},{"s":20,"a":50,"key":"20:50","ar":"قَالَ رَبُّنَا ٱلَّذِىٓ أَعْطَىٰ كُلَّ شَىْءٍ خَلْقَهُۥ ثُمَّ هَدَىٰ","en":"He said, \"Our Lord is He who gave each thing its form and then guided [it].\"","tr":"Qala rabbuna allatheeaAAta kulla shay-in khalqahu thumma hada","juz":16,"page":314},{"s":20,"a":51,"key":"20:51","ar":"قَالَ فَمَا بَالُ ٱلْقُرُونِ ٱلْأُولَىٰ","en":"[Pharaoh] said, \"Then what is the case of the former generations?\"","tr":"Qala fama balualqurooni al-oola","juz":16,"page":314},{"s":20,"a":52,"key":"20:52","ar":"قَالَ عِلْمُهَا عِندَ رَبِّى فِى كِتَـٰبٍ ۖ لَّا يَضِلُّ رَبِّى وَلَا يَنسَى","en":"[Moses] said, \"The knowledge thereof is with my Lord in a record. My Lord neither errs nor forgets.\"","tr":"Qala AAilmuha AAinda rabbeefee kitabin la yadillu rabbee walayansa","juz":16,"page":315},{"s":20,"a":53,"key":"20:53","ar":"ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ مَهْدًا وَسَلَكَ لَكُمْ فِيهَا سُبُلًا وَأَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً فَأَخْرَجْنَا بِهِۦٓ أَزْوَٰجًا مِّن نَّبَاتٍ شَتَّىٰ","en":"[It is He] who has made for you the earth as a bed [spread out] and inserted therein for you roadways and sent down from the sky, rain and produced thereby categories of various plants.","tr":"Allathee jaAAala lakumu al-ardamahdan wasalaka lakum feeha subulan waanzala mina assama-imaan faakhrajna bihi azwajan min nabatinshatta","juz":16,"page":315},{"s":20,"a":54,"key":"20:54","ar":"كُلُوا۟ وَٱرْعَوْا۟ أَنْعَـٰمَكُمْ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّأُو۟لِى ٱلنُّهَىٰ","en":"Eat [therefrom] and pasture your livestock. Indeed in that are signs for those of intelligence.","tr":"Kuloo warAAaw anAAamakum innafee thalika laayatin li-olee annuha","juz":16,"page":315},{"s":20,"a":55,"key":"20:55","ar":"۞ مِنْهَا خَلَقْنَـٰكُمْ وَفِيهَا نُعِيدُكُمْ وَمِنْهَا نُخْرِجُكُمْ تَارَةً أُخْرَىٰ","en":"From it [i.e., the earth] We created you, and into it We will return you, and from it We will extract you another time.","tr":"Minha khalaqnakum wafeehanuAAeedukum waminha nukhrijukum taratan okhra","juz":16,"page":315},{"s":20,"a":56,"key":"20:56","ar":"وَلَقَدْ أَرَيْنَـٰهُ ءَايَـٰتِنَا كُلَّهَا فَكَذَّبَ وَأَبَىٰ","en":"And We certainly showed him [i.e., Pharaoh] Our signs - all of them - but he denied and refused.","tr":"Walaqad araynahu ayatinakullaha fakaththaba waaba","juz":16,"page":315},{"s":20,"a":57,"key":"20:57","ar":"قَالَ أَجِئْتَنَا لِتُخْرِجَنَا مِنْ أَرْضِنَا بِسِحْرِكَ يَـٰمُوسَىٰ","en":"He said, \"Have you come to us to drive us out of our land with your magic, O Moses?","tr":"Qala aji/tana litukhrijanamin ardina bisihrika ya moosa","juz":16,"page":315},{"s":20,"a":58,"key":"20:58","ar":"فَلَنَأْتِيَنَّكَ بِسِحْرٍ مِّثْلِهِۦ فَٱجْعَلْ بَيْنَنَا وَبَيْنَكَ مَوْعِدًا لَّا نُخْلِفُهُۥ نَحْنُ وَلَآ أَنتَ مَكَانًا سُوًى","en":"Then we will surely bring you magic like it, so make between us and you an appointment, which we will not fail to keep and neither will you, in a place assigned.\"1","tr":"Falana/tiyannaka bisihrin mithlihi fajAAalbaynana wabaynaka mawAAidan la nukhlifuhu nahnuwala anta makanan suwa","juz":16,"page":315},{"s":20,"a":59,"key":"20:59","ar":"قَالَ مَوْعِدُكُمْ يَوْمُ ٱلزِّينَةِ وَأَن يُحْشَرَ ٱلنَّاسُ ضُحًى","en":"[Moses] said, \"Your appointment is on the day of the festival when the people assemble at mid-morning.\"1","tr":"Qala mawAAidukum yawmu azzeenatiwaan yuhshara annasu duha","juz":16,"page":315},{"s":20,"a":60,"key":"20:60","ar":"فَتَوَلَّىٰ فِرْعَوْنُ فَجَمَعَ كَيْدَهُۥ ثُمَّ أَتَىٰ","en":"So Pharaoh went away, put together his plan, and then came [to Moses].","tr":"Fatawalla firAAawnu fajamaAAa kaydahuthumma ata","juz":16,"page":315},{"s":20,"a":61,"key":"20:61","ar":"قَالَ لَهُم مُّوسَىٰ وَيْلَكُمْ لَا تَفْتَرُوا۟ عَلَى ٱللَّهِ كَذِبًا فَيُسْحِتَكُم بِعَذَابٍ ۖ وَقَدْ خَابَ مَنِ ٱفْتَرَىٰ","en":"Moses said to them [i.e., the magicians summoned by Pharaoh], \"Woe to you! Do not invent a lie against Allāh or He will exterminate you with a punishment; and he has failed who invents [such falsehood].\"","tr":"Qala lahum moosa waylakum lataftaroo AAala Allahi kathiban fayushitakumbiAAathabin waqad khaba mani iftara","juz":16,"page":315},{"s":20,"a":62,"key":"20:62","ar":"فَتَنَـٰزَعُوٓا۟ أَمْرَهُم بَيْنَهُمْ وَأَسَرُّوا۟ ٱلنَّجْوَىٰ","en":"So they disputed over their affair among themselves and concealed their private conversation.","tr":"FatanazaAAoo amrahum baynahumwaasarroo annajwa","juz":16,"page":315},{"s":20,"a":63,"key":"20:63","ar":"قَالُوٓا۟ إِنْ هَـٰذَٰنِ لَسَـٰحِرَٰنِ يُرِيدَانِ أَن يُخْرِجَاكُم مِّنْ أَرْضِكُم بِسِحْرِهِمَا وَيَذْهَبَا بِطَرِيقَتِكُمُ ٱلْمُثْلَىٰ","en":"They said, \"Indeed, these are two magicians who want to drive you out of your land with their magic and do away with your most exemplary way [i.e., religion or tradition].","tr":"Qaloo in hathani lasahiraniyureedani an yukhrijakum min ardikum bisihrihimawayathhaba bitareeqatikumu almuthla","juz":16,"page":315},{"s":20,"a":64,"key":"20:64","ar":"فَأَجْمِعُوا۟ كَيْدَكُمْ ثُمَّ ٱئْتُوا۟ صَفًّا ۚ وَقَدْ أَفْلَحَ ٱلْيَوْمَ مَنِ ٱسْتَعْلَىٰ","en":"So resolve upon your plan and then come [forward] in line. And he has succeeded today who overcomes.\"","tr":"FaajmiAAoo kaydakum thumma i/too saffanwaqad aflaha alyawma mani istaAAla","juz":16,"page":315},{"s":20,"a":65,"key":"20:65","ar":"قَالُوا۟ يَـٰمُوسَىٰٓ إِمَّآ أَن تُلْقِىَ وَإِمَّآ أَن نَّكُونَ أَوَّلَ مَنْ أَلْقَىٰ","en":"They said, \"O Moses, either you throw or we will be the first to throw.\"","tr":"Qaloo ya moosa immaan tulqiya wa-imma an nakoona awwala man alqa","juz":16,"page":316},{"s":20,"a":66,"key":"20:66","ar":"قَالَ بَلْ أَلْقُوا۟ ۖ فَإِذَا حِبَالُهُمْ وَعِصِيُّهُمْ يُخَيَّلُ إِلَيْهِ مِن سِحْرِهِمْ أَنَّهَا تَسْعَىٰ","en":"He said, \"Rather, you throw.\" And suddenly their ropes and staffs seemed to him from their magic that they were moving [like snakes].","tr":"Qala bal alqoo fa-itha hibaluhumwaAAisiyyuhum yukhayyalu ilayhi min sihrihim annahatasAAa","juz":16,"page":316},{"s":20,"a":67,"key":"20:67","ar":"فَأَوْجَسَ فِى نَفْسِهِۦ خِيفَةً مُّوسَىٰ","en":"And he sensed within himself apprehension, did Moses.","tr":"Faawjasa fee nafsihi kheefatan moosa","juz":16,"page":316},{"s":20,"a":68,"key":"20:68","ar":"قُلْنَا لَا تَخَفْ إِنَّكَ أَنتَ ٱلْأَعْلَىٰ","en":"We [i.e., Allāh] said, \"Fear not. Indeed, it is you who are superior.","tr":"Qulna la takhaf innaka antaal-aAAla","juz":16,"page":316},{"s":20,"a":69,"key":"20:69","ar":"وَأَلْقِ مَا فِى يَمِينِكَ تَلْقَفْ مَا صَنَعُوٓا۟ ۖ إِنَّمَا صَنَعُوا۟ كَيْدُ سَـٰحِرٍ ۖ وَلَا يُفْلِحُ ٱلسَّاحِرُ حَيْثُ أَتَىٰ","en":"And throw what is in your right hand; it will swallow up what they have crafted. What they have crafted is but the trick of a magician, and the magician will not succeed wherever he is.\"","tr":"Waalqi ma fee yameenika talqaf masanaAAoo innama sanaAAoo kaydu sahirinwala yuflihu assahiru haythuata","juz":16,"page":316},{"s":20,"a":70,"key":"20:70","ar":"فَأُلْقِىَ ٱلسَّحَرَةُ سُجَّدًا قَالُوٓا۟ ءَامَنَّا بِرَبِّ هَـٰرُونَ وَمُوسَىٰ","en":"So the magicians fell down in prostration.1 They said, \"We have believed in the Lord of Aaron and Moses.\"","tr":"Faolqiya assaharatu sujjadanqaloo amanna birabbi haroona wamoosa","juz":16,"page":316},{"s":20,"a":71,"key":"20:71","ar":"قَالَ ءَامَنتُمْ لَهُۥ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّهُۥ لَكَبِيرُكُمُ ٱلَّذِى عَلَّمَكُمُ ٱلسِّحْرَ ۖ فَلَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَـٰفٍ وَلَأُصَلِّبَنَّكُمْ فِى جُذُوعِ ٱلنَّخْلِ وَلَتَعْلَمُنَّ أَيُّنَآ أَشَدُّ عَذَابًا وَأَبْقَىٰ","en":"[Pharaoh] said, \"You believed him [i.e., Moses] before I gave you permission. Indeed, he is your leader who has taught you magic. So I will surely cut off your hands and your feet on opposite sides, and I will crucify you on the trunks of palm trees, and you will surely know which of us is more severe in [giving] punishment and more enduring.\"","tr":"Qala amantum lahu qabla an athanalakum innahu lakabeerukumu allathee AAallamakumu assihrafalaoqattiAAanna aydiyakum waarjulakum min khilafinwalaosallibannakum fee juthooAAi annakhliwalataAAlamunna ayyuna ashaddu AAathaban waabqa","juz":16,"page":316},{"s":20,"a":72,"key":"20:72","ar":"قَالُوا۟ لَن نُّؤْثِرَكَ عَلَىٰ مَا جَآءَنَا مِنَ ٱلْبَيِّنَـٰتِ وَٱلَّذِى فَطَرَنَا ۖ فَٱقْضِ مَآ أَنتَ قَاضٍ ۖ إِنَّمَا تَقْضِى هَـٰذِهِ ٱلْحَيَوٰةَ ٱلدُّنْيَآ","en":"They said, \"Never will we prefer you over what has come to us of clear proofs and [over] He who created us.1 So decree whatever you are to decree. You can only decree for this worldly life.","tr":"Qaloo lan nu/thiraka AAala majaana mina albayyinati wallatheefatarana faqdi ma anta qadininnama taqdee hathihi alhayataaddunya","juz":16,"page":316},{"s":20,"a":73,"key":"20:73","ar":"إِنَّآ ءَامَنَّا بِرَبِّنَا لِيَغْفِرَ لَنَا خَطَـٰيَـٰنَا وَمَآ أَكْرَهْتَنَا عَلَيْهِ مِنَ ٱلسِّحْرِ ۗ وَٱللَّهُ خَيْرٌ وَأَبْقَىٰٓ","en":"Indeed, we have believed in our Lord that He may forgive us our sins and what you compelled us [to do] of magic. And Allāh is better and more enduring.\"1","tr":"Inna amanna birabbinaliyaghfira lana khatayana wamaakrahtana AAalayhi mina assihri wallahukhayrun waabqa","juz":16,"page":316},{"s":20,"a":74,"key":"20:74","ar":"إِنَّهُۥ مَن يَأْتِ رَبَّهُۥ مُجْرِمًا فَإِنَّ لَهُۥ جَهَنَّمَ لَا يَمُوتُ فِيهَا وَلَا يَحْيَىٰ","en":"Indeed, whoever comes to his Lord as a criminal - indeed, for him is Hell; he will neither die therein nor live.","tr":"Innahu man ya/ti rabbahu mujriman fa-innalahu jahannama la yamootu feeha wala yahya","juz":16,"page":316},{"s":20,"a":75,"key":"20:75","ar":"وَمَن يَأْتِهِۦ مُؤْمِنًا قَدْ عَمِلَ ٱلصَّـٰلِحَـٰتِ فَأُو۟لَـٰٓئِكَ لَهُمُ ٱلدَّرَجَـٰتُ ٱلْعُلَىٰ","en":"But whoever comes to Him as a believer having done righteous deeds - for those will be the highest degrees [in position]:","tr":"Waman ya/tihi mu/minan qad AAamila assalihatifaola-ika lahumu addarajatu alAAula","juz":16,"page":316},{"s":20,"a":76,"key":"20:76","ar":"جَنَّـٰتُ عَدْنٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا ۚ وَذَٰلِكَ جَزَآءُ مَن تَزَكَّىٰ","en":"Gardens of perpetual residence beneath which rivers flow, wherein they abide eternally. And that is the reward of one who purifies himself.1","tr":"Jannatu AAadnin tajree min tahtihaal-anharu khalideena feeha wathalikajazao man tazakka","juz":16,"page":316},{"s":20,"a":77,"key":"20:77","ar":"وَلَقَدْ أَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَسْرِ بِعِبَادِى فَٱضْرِبْ لَهُمْ طَرِيقًا فِى ٱلْبَحْرِ يَبَسًا لَّا تَخَـٰفُ دَرَكًا وَلَا تَخْشَىٰ","en":"And We had inspired to Moses, \"Travel by night with My servants and strike for them a dry path through the sea; you will not fear being overtaken [by Pharaoh] nor be afraid [of drowning].\"","tr":"Walaqad awhayna ilamoosa an asri biAAibadee fadriblahum tareeqan fee albahri yabasan la takhafudarakan wala takhsha","juz":16,"page":317},{"s":20,"a":78,"key":"20:78","ar":"فَأَتْبَعَهُمْ فِرْعَوْنُ بِجُنُودِهِۦ فَغَشِيَهُم مِّنَ ٱلْيَمِّ مَا غَشِيَهُمْ","en":"So Pharaoh pursued them with his soldiers, and there covered them from the sea that which covered them,1","tr":"FaatbaAAahum firAAawnu bijunoodihifaghashiyahum mina alyammi ma ghashiyahum","juz":16,"page":317},{"s":20,"a":79,"key":"20:79","ar":"وَأَضَلَّ فِرْعَوْنُ قَوْمَهُۥ وَمَا هَدَىٰ","en":"And Pharaoh led his people astray and did not guide [them].","tr":"Waadalla firAAawnu qawmahu wamahada","juz":16,"page":317},{"s":20,"a":80,"key":"20:80","ar":"يَـٰبَنِىٓ إِسْرَٰٓءِيلَ قَدْ أَنجَيْنَـٰكُم مِّنْ عَدُوِّكُمْ وَوَٰعَدْنَـٰكُمْ جَانِبَ ٱلطُّورِ ٱلْأَيْمَنَ وَنَزَّلْنَا عَلَيْكُمُ ٱلْمَنَّ وَٱلسَّلْوَىٰ","en":"O Children of Israel, We delivered you from your enemy, and We made an appointment with you1 at the right side of the mount, and We sent down to you manna and quails,","tr":"Ya banee isra-eela qad anjaynakummin AAaduwwikum wawaAAadnakum janiba attoorial-aymana wanazzalna AAalaykumu almanna wassalwa","juz":16,"page":317},{"s":20,"a":81,"key":"20:81","ar":"كُلُوا۟ مِن طَيِّبَـٰتِ مَا رَزَقْنَـٰكُمْ وَلَا تَطْغَوْا۟ فِيهِ فَيَحِلَّ عَلَيْكُمْ غَضَبِى ۖ وَمَن يَحْلِلْ عَلَيْهِ غَضَبِى فَقَدْ هَوَىٰ","en":"[Saying], \"Eat from the good things with which We have provided you and do not transgress [or oppress others] therein, lest My anger should descend upon you. And he upon whom My anger descends has certainly fallen [i.e., perished].\"","tr":"Kuloo min tayyibati marazaqnakum wala tatghaw feehi fayahillaAAalaykum ghadabee waman yahlil AAalayhi ghadabeefaqad hawa","juz":16,"page":317},{"s":20,"a":82,"key":"20:82","ar":"وَإِنِّى لَغَفَّارٌ لِّمَن تَابَ وَءَامَنَ وَعَمِلَ صَـٰلِحًا ثُمَّ ٱهْتَدَىٰ","en":"But indeed, I am the Perpetual Forgiver of whoever repents and believes and does righteousness and then continues in guidance.","tr":"Wa-innee laghaffarun liman tabawaamana waAAamila salihan thumma ihtada","juz":16,"page":317},{"s":20,"a":83,"key":"20:83","ar":"۞ وَمَآ أَعْجَلَكَ عَن قَوْمِكَ يَـٰمُوسَىٰ","en":"[Allāh said], \"And what made you hasten from your people, O Moses?\"","tr":"Wama aAAjalaka AAan qawmika yamoosa","juz":16,"page":317},{"s":20,"a":84,"key":"20:84","ar":"قَالَ هُمْ أُو۟لَآءِ عَلَىٰٓ أَثَرِى وَعَجِلْتُ إِلَيْكَ رَبِّ لِتَرْضَىٰ","en":"He said, \"They are close upon my tracks, and I hastened to You, my Lord, that You be pleased.\"","tr":"Qala hum ola-i AAalaatharee waAAajiltu ilayka rabbi litarda","juz":16,"page":317},{"s":20,"a":85,"key":"20:85","ar":"قَالَ فَإِنَّا قَدْ فَتَنَّا قَوْمَكَ مِنۢ بَعْدِكَ وَأَضَلَّهُمُ ٱلسَّامِرِىُّ","en":"[Allāh] said, \"But indeed, We have tried your people after you [departed], and the Sāmirī1 has led them astray.\"","tr":"Qala fa-inna qad fatannaqawmaka min baAAdika waadallahumu assamiriy","juz":16,"page":317},{"s":20,"a":86,"key":"20:86","ar":"فَرَجَعَ مُوسَىٰٓ إِلَىٰ قَوْمِهِۦ غَضْبَـٰنَ أَسِفًا ۚ قَالَ يَـٰقَوْمِ أَلَمْ يَعِدْكُمْ رَبُّكُمْ وَعْدًا حَسَنًا ۚ أَفَطَالَ عَلَيْكُمُ ٱلْعَهْدُ أَمْ أَرَدتُّمْ أَن يَحِلَّ عَلَيْكُمْ غَضَبٌ مِّن رَّبِّكُمْ فَأَخْلَفْتُم مَّوْعِدِى","en":"So Moses returned to his people, angry and grieved.1 He said, \"O my people, did your Lord not make you a good promise?2 Then, was the time [of its fulfillment] too long for you, or did you wish that wrath from your Lord descend upon you, so you broke your promise [of obedience] to me?\"","tr":"FarajaAAa moosa ila qawmihighadbana asifan qala ya qawmi alamyaAAidkum rabbukum waAAdan hasanan afatalaAAalaykumu alAAahdu am aradtum an yahilla AAalaykum ghadabunmin rabbikum faakhlaftum mawAAidee","juz":16,"page":317},{"s":20,"a":87,"key":"20:87","ar":"قَالُوا۟ مَآ أَخْلَفْنَا مَوْعِدَكَ بِمَلْكِنَا وَلَـٰكِنَّا حُمِّلْنَآ أَوْزَارًا مِّن زِينَةِ ٱلْقَوْمِ فَقَذَفْنَـٰهَا فَكَذَٰلِكَ أَلْقَى ٱلسَّامِرِىُّ","en":"They said, \"We did not break our promise to you by our will, but we were made to carry burdens from the ornaments of the people [of Pharaoh], so we threw them [into the fire], and thus did the Sāmirī throw.\"","tr":"Qaloo ma akhlafnamawAAidaka bimalkina walakinna hummilnaawzaran min zeenati alqawmi faqathafnahafakathalika alqa assamiriy","juz":16,"page":317},{"s":20,"a":88,"key":"20:88","ar":"فَأَخْرَجَ لَهُمْ عِجْلًا جَسَدًا لَّهُۥ خُوَارٌ فَقَالُوا۟ هَـٰذَآ إِلَـٰهُكُمْ وَإِلَـٰهُ مُوسَىٰ فَنَسِىَ","en":"And he extracted for them [the statue of] a calf which had a lowing sound, and they said, \"This is your god and the god of Moses, but he forgot.\"","tr":"Faakhraja lahum AAijlan jasadan lahu khuwarunfaqaloo hatha ilahukum wa-ilahu moosafanasiy","juz":16,"page":318},{"s":20,"a":89,"key":"20:89","ar":"أَفَلَا يَرَوْنَ أَلَّا يَرْجِعُ إِلَيْهِمْ قَوْلًا وَلَا يَمْلِكُ لَهُمْ ضَرًّا وَلَا نَفْعًا","en":"Did they not see that it could not return to them any speech [i.e., response] and that it did not possess for them any harm or benefit?","tr":"Afala yarawna alla yarjiAAuilayhim qawlan wala yamliku lahum darran walanafAAa","juz":16,"page":318},{"s":20,"a":90,"key":"20:90","ar":"وَلَقَدْ قَالَ لَهُمْ هَـٰرُونُ مِن قَبْلُ يَـٰقَوْمِ إِنَّمَا فُتِنتُم بِهِۦ ۖ وَإِنَّ رَبَّكُمُ ٱلرَّحْمَـٰنُ فَٱتَّبِعُونِى وَأَطِيعُوٓا۟ أَمْرِى","en":"And Aaron had already told them before [the return of Moses], \"O my people, you are only being tested by it, and indeed, your Lord is the Most Merciful, so follow me and obey my order.\"","tr":"Walaqad qala lahum haroonu minqablu ya qawmi innama futintum bihi wa-innarabbakumu arrahmanu fattabiAAooneewaateeAAoo amree","juz":16,"page":318},{"s":20,"a":91,"key":"20:91","ar":"قَالُوا۟ لَن نَّبْرَحَ عَلَيْهِ عَـٰكِفِينَ حَتَّىٰ يَرْجِعَ إِلَيْنَا مُوسَىٰ","en":"They said, \"We will never cease being devoted to it [i.e., the calf] until Moses returns to us.\"","tr":"Qaloo lan nabraha AAalayhi AAakifeenahatta yarjiAAa ilayna moosa","juz":16,"page":318},{"s":20,"a":92,"key":"20:92","ar":"قَالَ يَـٰهَـٰرُونُ مَا مَنَعَكَ إِذْ رَأَيْتَهُمْ ضَلُّوٓا۟","en":"[Moses] said, \"O Aaron, what prevented you, when you saw them going astray,","tr":"Qala ya haroonu mamanaAAaka ith raaytahum dalloo","juz":16,"page":318},{"s":20,"a":93,"key":"20:93","ar":"أَلَّا تَتَّبِعَنِ ۖ أَفَعَصَيْتَ أَمْرِى","en":"From following me? Then have you disobeyed my order?\"","tr":"Alla tattabiAAani afaAAasaytaamree","juz":16,"page":318},{"s":20,"a":94,"key":"20:94","ar":"قَالَ يَبْنَؤُمَّ لَا تَأْخُذْ بِلِحْيَتِى وَلَا بِرَأْسِىٓ ۖ إِنِّى خَشِيتُ أَن تَقُولَ فَرَّقْتَ بَيْنَ بَنِىٓ إِسْرَٰٓءِيلَ وَلَمْ تَرْقُبْ قَوْلِى","en":"[Aaron] said, \"O son of my mother, do not seize [me] by my beard or by my head. Indeed, I feared that you would say, 'You caused division among the Children of Israel, and you did not observe [or await] my word.'\"","tr":"Qala yabnaomma la ta/khuthbilihyatee wala bira/see innee khasheetu an taqoolafarraqta bayna banee isra-eela walam tarqub qawlee","juz":16,"page":318},{"s":20,"a":95,"key":"20:95","ar":"قَالَ فَمَا خَطْبُكَ يَـٰسَـٰمِرِىُّ","en":"[Moses] said, \"And what is your case, O Sāmirī?\"","tr":"Qala fama khatbuka yasamiriy","juz":16,"page":318},{"s":20,"a":96,"key":"20:96","ar":"قَالَ بَصُرْتُ بِمَا لَمْ يَبْصُرُوا۟ بِهِۦ فَقَبَضْتُ قَبْضَةً مِّنْ أَثَرِ ٱلرَّسُولِ فَنَبَذْتُهَا وَكَذَٰلِكَ سَوَّلَتْ لِى نَفْسِى","en":"He said, \"I saw what they did not see, so I took a handful [of dust] from the track of the messenger1 and threw it,2 and thus did my soul entice me.\"","tr":"Qala basurtu bima lamyabsuroo bihi faqabadtu qabdatan min athariarrasooli fanabathtuha wakathalikasawwalat lee nafsee","juz":16,"page":318},{"s":20,"a":97,"key":"20:97","ar":"قَالَ فَٱذْهَبْ فَإِنَّ لَكَ فِى ٱلْحَيَوٰةِ أَن تَقُولَ لَا مِسَاسَ ۖ وَإِنَّ لَكَ مَوْعِدًا لَّن تُخْلَفَهُۥ ۖ وَٱنظُرْ إِلَىٰٓ إِلَـٰهِكَ ٱلَّذِى ظَلْتَ عَلَيْهِ عَاكِفًا ۖ لَّنُحَرِّقَنَّهُۥ ثُمَّ لَنَنسِفَنَّهُۥ فِى ٱلْيَمِّ نَسْفًا","en":"[Moses] said, \"Then go. And indeed, it is [decreed] for you in [this] life to say, 'No contact.'1 And indeed, you have an appointment [in the Hereafter] you will not fail to keep. And look at your 'god' to which you remained devoted. We will surely burn it and blow it [i.e., its ashes] into the sea with a blast.","tr":"Qala fathhab fa-innalaka fee alhayati an taqoola la misasawa-inna laka mawAAidan lan tukhlafahu wanthurila ilahika allathee thaltaAAalayhi AAakifan lanuharriqannahu thummalanansifannahu fee alyammi nasfa","juz":16,"page":318},{"s":20,"a":98,"key":"20:98","ar":"إِنَّمَآ إِلَـٰهُكُمُ ٱللَّهُ ٱلَّذِى لَآ إِلَـٰهَ إِلَّا هُوَ ۚ وَسِعَ كُلَّ شَىْءٍ عِلْمًا","en":"Your god is only Allāh, except for whom there is no deity. He has encompassed all things in knowledge.\"","tr":"Innama ilahukumu Allahuallathee la ilaha illa huwa wasiAAakulla shay-in AAilma","juz":16,"page":318},{"s":20,"a":99,"key":"20:99","ar":"كَذَٰلِكَ نَقُصُّ عَلَيْكَ مِنْ أَنۢبَآءِ مَا قَدْ سَبَقَ ۚ وَقَدْ ءَاتَيْنَـٰكَ مِن لَّدُنَّا ذِكْرًا","en":"Thus, [O Muḥammad], We relate to you from the news of what has preceded. And We have certainly given you from Us a message [i.e., the Qur’ān].","tr":"Kathalika naqussu AAalayka minanba-i ma qad sabaqa waqad ataynakamin ladunna thikra","juz":16,"page":319},{"s":20,"a":100,"key":"20:100","ar":"مَّنْ أَعْرَضَ عَنْهُ فَإِنَّهُۥ يَحْمِلُ يَوْمَ ٱلْقِيَـٰمَةِ وِزْرًا","en":"Whoever turns away from it - then indeed, he will bear on the Day of Resurrection a burden [i.e., great sin],","tr":"Man aAArada AAanhu fa-innahu yahmiluyawma alqiyamati wizra","juz":16,"page":319},{"s":20,"a":101,"key":"20:101","ar":"خَـٰلِدِينَ فِيهِ ۖ وَسَآءَ لَهُمْ يَوْمَ ٱلْقِيَـٰمَةِ حِمْلًا","en":"[Abiding] eternally therein,1 and evil it is for them on the Day of Resurrection as a load -","tr":"Khalideena feehi wasaa lahumyawma alqiyamati himla","juz":16,"page":319},{"s":20,"a":102,"key":"20:102","ar":"يَوْمَ يُنفَخُ فِى ٱلصُّورِ ۚ وَنَحْشُرُ ٱلْمُجْرِمِينَ يَوْمَئِذٍ زُرْقًا","en":"The Day the Horn will be blown. And We will gather the criminals, that Day, blue-eyed.1","tr":"Yawma yunfakhu fee assooriwanahshuru almujrimeena yawma-ithin zurqa","juz":16,"page":319},{"s":20,"a":103,"key":"20:103","ar":"يَتَخَـٰفَتُونَ بَيْنَهُمْ إِن لَّبِثْتُمْ إِلَّا عَشْرًا","en":"They will murmur among themselves, \"You remained not but ten [days in the world].\"","tr":"Yatakhafatoona baynahum in labithtumilla AAashra","juz":16,"page":319},{"s":20,"a":104,"key":"20:104","ar":"نَّحْنُ أَعْلَمُ بِمَا يَقُولُونَ إِذْ يَقُولُ أَمْثَلُهُمْ طَرِيقَةً إِن لَّبِثْتُمْ إِلَّا يَوْمًا","en":"We are most knowing of what they say when the best of them in manner [i.e., wisdom or speech] will say, \"You remained not but one day.\"","tr":"Nahnu aAAlamu bima yaqooloonaith yaqoolu amthaluhum tareeqatan in labithtum illayawma","juz":16,"page":319},{"s":20,"a":105,"key":"20:105","ar":"وَيَسْـَٔلُونَكَ عَنِ ٱلْجِبَالِ فَقُلْ يَنسِفُهَا رَبِّى نَسْفًا","en":"And they ask you about the mountains, so say, \"My Lord will blow them away with a blast.1","tr":"Wayas-aloonaka AAani aljibali faqulyansifuha rabbee nasfa","juz":16,"page":319},{"s":20,"a":106,"key":"20:106","ar":"فَيَذَرُهَا قَاعًا صَفْصَفًا","en":"And He will leave it [i.e., the earth] a level plain;","tr":"Fayatharuha qaAAan safsafa","juz":16,"page":319},{"s":20,"a":107,"key":"20:107","ar":"لَّا تَرَىٰ فِيهَا عِوَجًا وَلَآ أَمْتًا","en":"You will not see therein a depression or an elevation.\"","tr":"La tara feeha AAiwajanwala amta","juz":16,"page":319},{"s":20,"a":108,"key":"20:108","ar":"يَوْمَئِذٍ يَتَّبِعُونَ ٱلدَّاعِىَ لَا عِوَجَ لَهُۥ ۖ وَخَشَعَتِ ٱلْأَصْوَاتُ لِلرَّحْمَـٰنِ فَلَا تَسْمَعُ إِلَّا هَمْسًا","en":"That Day, they [i.e., everyone] will follow [the call of] the Caller1 [with] no deviation therefrom, and [all] voices will be stilled before the Most Merciful, so you will not hear except a whisper [of footsteps].","tr":"Yawma-ithin yattabiAAoona addaAAiyala AAiwaja lahu wakhashaAAati al-aswatu lirrahmanifala tasmaAAu illa hamsa","juz":16,"page":319},{"s":20,"a":109,"key":"20:109","ar":"يَوْمَئِذٍ لَّا تَنفَعُ ٱلشَّفَـٰعَةُ إِلَّا مَنْ أَذِنَ لَهُ ٱلرَّحْمَـٰنُ وَرَضِىَ لَهُۥ قَوْلًا","en":"That Day, no intercession will benefit except [that of] one to whom the Most Merciful has given permission and has accepted his word.","tr":"Yawma-ithin la tanfaAAu ashshafaAAatuilla man athina lahu arrahmanuwaradiya lahu qawla","juz":16,"page":319},{"s":20,"a":110,"key":"20:110","ar":"يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَلَا يُحِيطُونَ بِهِۦ عِلْمًا","en":"He [i.e., Allāh] knows what is [presently] before them and what will be after them,1 but they do not encompass it [i.e., what He knows] in knowledge.","tr":"YaAAlamu ma bayna aydeehim wamakhalfahum wala yuheetoona bihi AAilma","juz":16,"page":319},{"s":20,"a":111,"key":"20:111","ar":"۞ وَعَنَتِ ٱلْوُجُوهُ لِلْحَىِّ ٱلْقَيُّومِ ۖ وَقَدْ خَابَ مَنْ حَمَلَ ظُلْمًا","en":"And [all] faces will be humbled before the Ever-Living, the Self-Sustaining.1 And he will have failed who carries injustice.2","tr":"WaAAanati alwujoohu lilhayyialqayyoomi waqad khaba man hamala thulma","juz":16,"page":319},{"s":20,"a":112,"key":"20:112","ar":"وَمَن يَعْمَلْ مِنَ ٱلصَّـٰلِحَـٰتِ وَهُوَ مُؤْمِنٌ فَلَا يَخَافُ ظُلْمًا وَلَا هَضْمًا","en":"But he who does of righteous deeds while he is a believer - he will neither fear injustice nor deprivation.","tr":"Waman yaAAmal mina assalihatiwahuwa mu/minun fala yakhafu thulmanwala hadma","juz":16,"page":319},{"s":20,"a":113,"key":"20:113","ar":"وَكَذَٰلِكَ أَنزَلْنَـٰهُ قُرْءَانًا عَرَبِيًّا وَصَرَّفْنَا فِيهِ مِنَ ٱلْوَعِيدِ لَعَلَّهُمْ يَتَّقُونَ أَوْ يُحْدِثُ لَهُمْ ذِكْرًا","en":"And thus We have sent it down as an Arabic Qur’ān1 and have diversified therein the warnings that perhaps they will avoid [sin] or it would cause them remembrance.","tr":"Wakathalika anzalnahu qur-ananAAarabiyyan wasarrafna feehi mina alwaAAeedilaAAallahum yattaqoona aw yuhdithu lahum thikra","juz":16,"page":319},{"s":20,"a":114,"key":"20:114","ar":"فَتَعَـٰلَى ٱللَّهُ ٱلْمَلِكُ ٱلْحَقُّ ۗ وَلَا تَعْجَلْ بِٱلْقُرْءَانِ مِن قَبْلِ أَن يُقْضَىٰٓ إِلَيْكَ وَحْيُهُۥ ۖ وَقُل رَّبِّ زِدْنِى عِلْمًا","en":"So high [above all] is Allāh, the Sovereign,1 the Truth.2 And, [O Muḥammad], do not hasten with [recitation of] the Qur’ān before its revelation is completed to you, and say, \"My Lord, increase me in knowledge.\"","tr":"FataAAala Allahualmaliku alhaqqu wala taAAjal bilqur-animin qabli an yuqda ilayka wahyuhu waqul rabbizidnee AAilma","juz":16,"page":320},{"s":20,"a":115,"key":"20:115","ar":"وَلَقَدْ عَهِدْنَآ إِلَىٰٓ ءَادَمَ مِن قَبْلُ فَنَسِىَ وَلَمْ نَجِدْ لَهُۥ عَزْمًا","en":"And We had already taken a promise from Adam before, but he forgot; and We found not in him determination.1","tr":"Walaqad AAahidna ila adamamin qablu fanasiya walam najid lahu AAazma","juz":16,"page":320},{"s":20,"a":116,"key":"20:116","ar":"وَإِذْ قُلْنَا لِلْمَلَـٰٓئِكَةِ ٱسْجُدُوا۟ لِـَٔادَمَ فَسَجَدُوٓا۟ إِلَّآ إِبْلِيسَ أَبَىٰ","en":"And [mention] when We said to the angels, \"Prostrate to Adam,\" and they prostrated, except Iblees;1 he refused.","tr":"Wa-ith qulna lilmala-ikatiosjudoo li-adama fasajadoo illa ibleesa aba","juz":16,"page":320},{"s":20,"a":117,"key":"20:117","ar":"فَقُلْنَا يَـٰٓـَٔادَمُ إِنَّ هَـٰذَا عَدُوٌّ لَّكَ وَلِزَوْجِكَ فَلَا يُخْرِجَنَّكُمَا مِنَ ٱلْجَنَّةِ فَتَشْقَىٰٓ","en":"So We said, \"O Adam, indeed this is an enemy to you and to your wife. Then let him not remove you from Paradise so you would suffer.","tr":"Faqulna ya adamu innahatha AAaduwwun laka walizawjika falayukhrijannakuma mina aljannati fatashqa","juz":16,"page":320},{"s":20,"a":118,"key":"20:118","ar":"إِنَّ لَكَ أَلَّا تَجُوعَ فِيهَا وَلَا تَعْرَىٰ","en":"Indeed, it is [promised] for you not to be hungry therein or be unclothed.","tr":"Inna laka alla tajooAAa feehawala taAAra","juz":16,"page":320},{"s":20,"a":119,"key":"20:119","ar":"وَأَنَّكَ لَا تَظْمَؤُا۟ فِيهَا وَلَا تَضْحَىٰ","en":"And indeed, you will not be thirsty therein or be hot from the sun.\"","tr":"Waannaka la tathmaofeeha wala tadha","juz":16,"page":320},{"s":20,"a":120,"key":"20:120","ar":"فَوَسْوَسَ إِلَيْهِ ٱلشَّيْطَـٰنُ قَالَ يَـٰٓـَٔادَمُ هَلْ أَدُلُّكَ عَلَىٰ شَجَرَةِ ٱلْخُلْدِ وَمُلْكٍ لَّا يَبْلَىٰ","en":"Then Satan whispered to him; he said, \"O Adam, shall I direct you to the tree of eternity and possession that will not deteriorate?\"","tr":"Fawaswasa ilayhi ashshaytanuqala ya adamu hal adulluka AAalashajarati alkhuldi wamulkin la yabla","juz":16,"page":320},{"s":20,"a":121,"key":"20:121","ar":"فَأَكَلَا مِنْهَا فَبَدَتْ لَهُمَا سَوْءَٰتُهُمَا وَطَفِقَا يَخْصِفَانِ عَلَيْهِمَا مِن وَرَقِ ٱلْجَنَّةِ ۚ وَعَصَىٰٓ ءَادَمُ رَبَّهُۥ فَغَوَىٰ","en":"And they [i.e., Adam and his wife] ate of it, and their private parts became apparent to them, and they began to fasten over themselves from the leaves of Paradise. And Adam disobeyed his Lord and erred.","tr":"Faakala minha fabadat lahumasaw-atuhuma watafiqa yakhsifaniAAalayhima min waraqi aljannati waAAasa adamurabbahu faghawa","juz":16,"page":320},{"s":20,"a":122,"key":"20:122","ar":"ثُمَّ ٱجْتَبَـٰهُ رَبُّهُۥ فَتَابَ عَلَيْهِ وَهَدَىٰ","en":"Then his Lord chose him and turned to him in forgiveness and guided [him].","tr":"Thumma ijtabahu rabbuhu fatabaAAalayhi wahada","juz":16,"page":320},{"s":20,"a":123,"key":"20:123","ar":"قَالَ ٱهْبِطَا مِنْهَا جَمِيعًۢا ۖ بَعْضُكُمْ لِبَعْضٍ عَدُوٌّ ۖ فَإِمَّا يَأْتِيَنَّكُم مِّنِّى هُدًى فَمَنِ ٱتَّبَعَ هُدَاىَ فَلَا يَضِلُّ وَلَا يَشْقَىٰ","en":"[Allāh] said, \"Descend from it [i.e., Paradise] - all, [your descendants] being enemies to one another. And if there should come to you guidance from Me - then whoever follows My guidance will neither go astray [in the world] nor suffer [in the Hereafter].","tr":"Qala ihbita minhajameeAAan baAAdukum libaAAdin AAaduwwun fa-immaya/tiyannakum minnee hudan famani ittabaAAa hudaya falayadillu wala yashqa","juz":16,"page":320},{"s":20,"a":124,"key":"20:124","ar":"وَمَنْ أَعْرَضَ عَن ذِكْرِى فَإِنَّ لَهُۥ مَعِيشَةً ضَنكًا وَنَحْشُرُهُۥ يَوْمَ ٱلْقِيَـٰمَةِ أَعْمَىٰ","en":"And whoever turns away from My remembrance - indeed, he will have a depressed [i.e., difficult] life, and We will gather [i.e., raise] him on the Day of Resurrection blind.\"","tr":"Waman aAArada AAan thikreefa-inna lahu maAAeeshatan danka wanahshuruhuyawma alqiyamati aAAma","juz":16,"page":320},{"s":20,"a":125,"key":"20:125","ar":"قَالَ رَبِّ لِمَ حَشَرْتَنِىٓ أَعْمَىٰ وَقَدْ كُنتُ بَصِيرًا","en":"He will say, \"My Lord, why have you raised me blind while I was [once] seeing?\"","tr":"Qala rabbi lima hashartaneeaAAma waqad kuntu baseera","juz":16,"page":320},{"s":20,"a":126,"key":"20:126","ar":"قَالَ كَذَٰلِكَ أَتَتْكَ ءَايَـٰتُنَا فَنَسِيتَهَا ۖ وَكَذَٰلِكَ ٱلْيَوْمَ تُنسَىٰ","en":"[Allāh] will say, \"Thus did Our signs come to you, and you forgot [i.e., disregarded] them; and thus will you this Day be forgotten.\"","tr":"Qala kathalika atatka ayatunafanaseetaha wakathalika alyawma tunsa","juz":16,"page":321},{"s":20,"a":127,"key":"20:127","ar":"وَكَذَٰلِكَ نَجْزِى مَنْ أَسْرَفَ وَلَمْ يُؤْمِنۢ بِـَٔايَـٰتِ رَبِّهِۦ ۚ وَلَعَذَابُ ٱلْـَٔاخِرَةِ أَشَدُّ وَأَبْقَىٰٓ","en":"And thus do We recompense he who transgressed and did not believe in the signs of his Lord. And the punishment of the Hereafter is more severe and more enduring.1","tr":"Wakathalika najzee man asrafa walamyu/min bi-ayati rabbihi walaAAathabu al-akhiratiashaddu waabqa","juz":16,"page":321},{"s":20,"a":128,"key":"20:128","ar":"أَفَلَمْ يَهْدِ لَهُمْ كَمْ أَهْلَكْنَا قَبْلَهُم مِّنَ ٱلْقُرُونِ يَمْشُونَ فِى مَسَـٰكِنِهِمْ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّأُو۟لِى ٱلنُّهَىٰ","en":"Then, has it not become clear to them how many generations We destroyed before them as they walk among their dwellings? Indeed in that are signs for those of intelligence.","tr":"Afalam yahdi lahum kam ahlaknaqablahum mina alqurooni yamshoona fee masakinihim inna feethalika laayatin li-olee annuha","juz":16,"page":321},{"s":20,"a":129,"key":"20:129","ar":"وَلَوْلَا كَلِمَةٌ سَبَقَتْ مِن رَّبِّكَ لَكَانَ لِزَامًا وَأَجَلٌ مُّسَمًّى","en":"And if not for a word1 that preceded from your Lord, it [i.e., punishment] would have been an obligation [due immediately],2 and [if not for] a specified term [decreed].","tr":"Walawla kalimatun sabaqat minrabbika lakana lizaman waajalun musamma","juz":16,"page":321},{"s":20,"a":130,"key":"20:130","ar":"فَٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ ٱلشَّمْسِ وَقَبْلَ غُرُوبِهَا ۖ وَمِنْ ءَانَآئِ ٱلَّيْلِ فَسَبِّحْ وَأَطْرَافَ ٱلنَّهَارِ لَعَلَّكَ تَرْضَىٰ","en":"So be patient over what they say and exalt [Allāh] with praise of your Lord before the rising of the sun and before its setting; and during periods of the night [exalt Him] and at the ends of the day, that you may be satisfied.","tr":"Fasbir AAala mayaqooloona wasabbih bihamdi rabbika qabla tulooAAiashshamsi waqabla ghuroobiha wamin ana-iallayli fasabbih waatrafa annaharilaAAallaka tarda","juz":16,"page":321},{"s":20,"a":131,"key":"20:131","ar":"وَلَا تَمُدَّنَّ عَيْنَيْكَ إِلَىٰ مَا مَتَّعْنَا بِهِۦٓ أَزْوَٰجًا مِّنْهُمْ زَهْرَةَ ٱلْحَيَوٰةِ ٱلدُّنْيَا لِنَفْتِنَهُمْ فِيهِ ۚ وَرِزْقُ رَبِّكَ خَيْرٌ وَأَبْقَىٰ","en":"And do not extend your eyes toward that by which We have given enjoyment to [some] categories of them, [its being but] the splendor of worldly life by which We test them. And the provision of your Lord is better and more enduring.","tr":"Wala tamuddanna AAaynayka ilama mattaAAna bihi azwajan minhum zahrata alhayatiaddunya linaftinahum feehi warizqu rabbika khayrunwaabqa","juz":16,"page":321},{"s":20,"a":132,"key":"20:132","ar":"وَأْمُرْ أَهْلَكَ بِٱلصَّلَوٰةِ وَٱصْطَبِرْ عَلَيْهَا ۖ لَا نَسْـَٔلُكَ رِزْقًا ۖ نَّحْنُ نَرْزُقُكَ ۗ وَٱلْعَـٰقِبَةُ لِلتَّقْوَىٰ","en":"And enjoin prayer upon your family [and people] and be steadfast therein. We ask you not for provision; We provide for you, and the [best] outcome is for [those of] righteousness.","tr":"Wa/mur ahlaka bissalatiwastabir AAalayha la nas-alukarizqan nahnu narzuquka walAAaqibatu littaqwa","juz":16,"page":321},{"s":20,"a":133,"key":"20:133","ar":"وَقَالُوا۟ لَوْلَا يَأْتِينَا بِـَٔايَةٍ مِّن رَّبِّهِۦٓ ۚ أَوَلَمْ تَأْتِهِم بَيِّنَةُ مَا فِى ٱلصُّحُفِ ٱلْأُولَىٰ","en":"And they say, \"Why does he not bring us a sign from his Lord?\" Has there not come to them evidence of what was in the former scriptures?1","tr":"Waqaloo lawla ya/teenabi-ayatin min rabbihi awa lam ta/tihim bayyinatu mafee assuhufi al-oola","juz":16,"page":321},{"s":20,"a":134,"key":"20:134","ar":"وَلَوْ أَنَّآ أَهْلَكْنَـٰهُم بِعَذَابٍ مِّن قَبْلِهِۦ لَقَالُوا۟ رَبَّنَا لَوْلَآ أَرْسَلْتَ إِلَيْنَا رَسُولًا فَنَتَّبِعَ ءَايَـٰتِكَ مِن قَبْلِ أَن نَّذِلَّ وَنَخْزَىٰ","en":"And if We had destroyed them with a punishment before him,1 they would have said, \"Our Lord, why did You not send to us a messenger so we could have followed Your verses [i.e., teachings] before we were humiliated and disgraced?\"","tr":"Walaw anna ahlaknahum biAAathabinmin qablihi laqaloo rabbana lawla arsaltailayna rasoolan fanattabiAAa ayatika minqabli an nathilla wanakhza","juz":16,"page":321},{"s":20,"a":135,"key":"20:135","ar":"قُلْ كُلٌّ مُّتَرَبِّصٌ فَتَرَبَّصُوا۟ ۖ فَسَتَعْلَمُونَ مَنْ أَصْحَـٰبُ ٱلصِّرَٰطِ ٱلسَّوِىِّ وَمَنِ ٱهْتَدَىٰ","en":"Say, \"Each [of us] is waiting;1 so wait. For you will know who are the companions of the sound path and who is guided.\"","tr":"Qul kullun mutarabbisun fatarabbasoofasataAAlamoona man as-habu assiratiassawiyyi wamani ihtada","juz":16,"page":321},{"s":21,"a":1,"key":"21:1","ar":" ٱقْتَرَبَ لِلنَّاسِ حِسَابُهُمْ وَهُمْ فِى غَفْلَةٍ مُّعْرِضُونَ","en":"[The time of] their account has approached for the people, while they are in heedlessness turning away.","tr":"Iqtaraba linnasi hisabuhumwahum fee ghaflatin muAAridoon","juz":17,"page":322},{"s":21,"a":2,"key":"21:2","ar":"مَا يَأْتِيهِم مِّن ذِكْرٍ مِّن رَّبِّهِم مُّحْدَثٍ إِلَّا ٱسْتَمَعُوهُ وَهُمْ يَلْعَبُونَ","en":"No mention [i.e., revelation] comes to them anew from their Lord except that they listen to it while they are at play","tr":"Ma ya/teehim min thikrin minrabbihim muhdathin illa istamaAAoohu wahumyalAAaboon","juz":17,"page":322},{"s":21,"a":3,"key":"21:3","ar":"لَاهِيَةً قُلُوبُهُمْ ۗ وَأَسَرُّوا۟ ٱلنَّجْوَى ٱلَّذِينَ ظَلَمُوا۟ هَلْ هَـٰذَآ إِلَّا بَشَرٌ مِّثْلُكُمْ ۖ أَفَتَأْتُونَ ٱلسِّحْرَ وَأَنتُمْ تُبْصِرُونَ","en":"With their hearts distracted. And those who do wrong conceal their private conversation, [saying], \"Is this [Prophet] except a human being like you? So would you approach magic while you are aware [of it]?\"","tr":"Lahiyatan quloobuhum waasarroo annajwaallatheena thalamoo hal hatha illabasharun mithlukum afata/toona assihra waantum tubsiroon","juz":17,"page":322},{"s":21,"a":4,"key":"21:4","ar":"قَالَ رَبِّى يَعْلَمُ ٱلْقَوْلَ فِى ٱلسَّمَآءِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"He [the Prophet (ﷺ)] said, \"My Lord knows whatever is said throughout the heaven and earth, and He is the Hearing, the Knowing.\"","tr":"Qala rabbee yaAAlamu alqawla fee assama-iwal-ardi wahuwa assameeAAu alAAaleem","juz":17,"page":322},{"s":21,"a":5,"key":"21:5","ar":"بَلْ قَالُوٓا۟ أَضْغَـٰثُ أَحْلَـٰمٍۭ بَلِ ٱفْتَرَىٰهُ بَلْ هُوَ شَاعِرٌ فَلْيَأْتِنَا بِـَٔايَةٍ كَمَآ أُرْسِلَ ٱلْأَوَّلُونَ","en":"But they say, \"[The revelation is but] a mixture of false dreams; rather, he has invented it; rather, he is a poet. So let him bring us a sign just as the previous [messengers] were sent [with miracles].\"","tr":"Bal qaloo adghathu ahlaminbali iftarahu bal huwa shaAAirun falya/tinabi-ayatin kama orsila al-awwaloon","juz":17,"page":322},{"s":21,"a":6,"key":"21:6","ar":"مَآ ءَامَنَتْ قَبْلَهُم مِّن قَرْيَةٍ أَهْلَكْنَـٰهَآ ۖ أَفَهُمْ يُؤْمِنُونَ","en":"Not a [single] city which We destroyed believed before them,1 so will they believe?","tr":"Ma amanat qablahum min qaryatinahlaknaha afahum yu/minoon","juz":17,"page":322},{"s":21,"a":7,"key":"21:7","ar":"وَمَآ أَرْسَلْنَا قَبْلَكَ إِلَّا رِجَالًا نُّوحِىٓ إِلَيْهِمْ ۖ فَسْـَٔلُوٓا۟ أَهْلَ ٱلذِّكْرِ إِن كُنتُمْ لَا تَعْلَمُونَ","en":"And We sent not before you, [O Muḥammad], except men to whom We revealed [the message], so ask the people of the message [i.e., former scriptures] if you do not know.","tr":"Wama arsalna qablaka illarijalan noohee ilayhim fas-aloo ahla aththikriin kuntum la taAAlamoon","juz":17,"page":322},{"s":21,"a":8,"key":"21:8","ar":"وَمَا جَعَلْنَـٰهُمْ جَسَدًا لَّا يَأْكُلُونَ ٱلطَّعَامَ وَمَا كَانُوا۟ خَـٰلِدِينَ","en":"And We did not make them [i.e., the prophets] forms not eating food,1 nor were they immortal [on earth].","tr":"Wama jaAAalnahum jasadan laya/kuloona attaAAama wama kanookhalideen","juz":17,"page":322},{"s":21,"a":9,"key":"21:9","ar":"ثُمَّ صَدَقْنَـٰهُمُ ٱلْوَعْدَ فَأَنجَيْنَـٰهُمْ وَمَن نَّشَآءُ وَأَهْلَكْنَا ٱلْمُسْرِفِينَ","en":"Then1 We fulfilled for them the promise, and We saved them and whom We willed and destroyed the transgressors.","tr":"Thumma sadaqnahumu alwaAAdafaanjaynahum waman nashao waahlaknaalmusrifeen","juz":17,"page":322},{"s":21,"a":10,"key":"21:10","ar":"لَقَدْ أَنزَلْنَآ إِلَيْكُمْ كِتَـٰبًا فِيهِ ذِكْرُكُمْ ۖ أَفَلَا تَعْقِلُونَ","en":"We have certainly sent down to you a Book [i.e., the Qur’ān] in which is your mention.1 Then will you not reason?","tr":"Laqad anzalna ilaykum kitabanfeehi thikrukum afala taAAqiloon","juz":17,"page":322},{"s":21,"a":11,"key":"21:11","ar":"وَكَمْ قَصَمْنَا مِن قَرْيَةٍ كَانَتْ ظَالِمَةً وَأَنشَأْنَا بَعْدَهَا قَوْمًا ءَاخَرِينَ","en":"And how many a city which was unjust1 have We shattered and produced after it another people.","tr":"Wakam qasamna min qaryatin kanatthalimatan waansha/na baAAdahaqawman akhareen","juz":17,"page":323},{"s":21,"a":12,"key":"21:12","ar":"فَلَمَّآ أَحَسُّوا۟ بَأْسَنَآ إِذَا هُم مِّنْهَا يَرْكُضُونَ","en":"And when they [i.e., its inhabitants] perceived Our punishment, at once they fled from it.","tr":"Falamma ahassoo ba/sanaitha hum minha yarkudoon","juz":17,"page":323},{"s":21,"a":13,"key":"21:13","ar":"لَا تَرْكُضُوا۟ وَٱرْجِعُوٓا۟ إِلَىٰ مَآ أُتْرِفْتُمْ فِيهِ وَمَسَـٰكِنِكُمْ لَعَلَّكُمْ تُسْـَٔلُونَ","en":"[Some angels said], \"Do not flee but return to where you were given luxury and to your homes - perhaps you will be questioned.\"1","tr":"La tarkudoo warjiAAooila ma otriftum feehi wamasakinikumlaAAallakum tus-aloon","juz":17,"page":323},{"s":21,"a":14,"key":"21:14","ar":"قَالُوا۟ يَـٰوَيْلَنَآ إِنَّا كُنَّا ظَـٰلِمِينَ","en":"They said, \"O woe to us! Indeed, we were wrongdoers.\"","tr":"Qaloo ya waylana innakunna thalimeen","juz":17,"page":323},{"s":21,"a":15,"key":"21:15","ar":"فَمَا زَالَت تِّلْكَ دَعْوَىٰهُمْ حَتَّىٰ جَعَلْنَـٰهُمْ حَصِيدًا خَـٰمِدِينَ","en":"And that declaration of theirs did not cease until We made them [as] a harvest [mowed down], extinguished [like a fire].","tr":"Fama zalat tilka daAAwahumhatta jaAAalnahum haseedan khamideen","juz":17,"page":323},{"s":21,"a":16,"key":"21:16","ar":"وَمَا خَلَقْنَا ٱلسَّمَآءَ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا لَـٰعِبِينَ","en":"And We did not create the heaven and earth and that between them in play.","tr":"Wama khalaqna assamaawal-arda wama baynahuma laAAibeen","juz":17,"page":323},{"s":21,"a":17,"key":"21:17","ar":"لَوْ أَرَدْنَآ أَن نَّتَّخِذَ لَهْوًا لَّٱتَّخَذْنَـٰهُ مِن لَّدُنَّآ إِن كُنَّا فَـٰعِلِينَ","en":"Had We intended to take a diversion,1 We could have taken it from [what is] with Us - if [indeed] We were to do so.","tr":"Law aradna an nattakhithalahwan lattakhathnahu min ladunna inkunna faAAileen","juz":17,"page":323},{"s":21,"a":18,"key":"21:18","ar":"بَلْ نَقْذِفُ بِٱلْحَقِّ عَلَى ٱلْبَـٰطِلِ فَيَدْمَغُهُۥ فَإِذَا هُوَ زَاهِقٌ ۚ وَلَكُمُ ٱلْوَيْلُ مِمَّا تَصِفُونَ","en":"Rather, We dash the truth upon falsehood, and it destroys it,1 and thereupon it departs. And for you is destruction from that which you describe.2","tr":"Bal naqthifu bilhaqqiAAala albatili fayadmaghuhu fa-itha huwa zahiqunwalakumu alwaylu mimma tasifoon","juz":17,"page":323},{"s":21,"a":19,"key":"21:19","ar":"وَلَهُۥ مَن فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَمَنْ عِندَهُۥ لَا يَسْتَكْبِرُونَ عَنْ عِبَادَتِهِۦ وَلَا يَسْتَحْسِرُونَ","en":"To Him belongs whoever is in the heavens and the earth. And those near Him [i.e., the angels] are not prevented by arrogance from His worship, nor do they tire.","tr":"Walahu man fee assamawatiwal-ardi waman AAindahu la yastakbiroonaAAan AAibadatihi wala yastahsiroon","juz":17,"page":323},{"s":21,"a":20,"key":"21:20","ar":"يُسَبِّحُونَ ٱلَّيْلَ وَٱلنَّهَارَ لَا يَفْتُرُونَ","en":"They exalt [Him] night and day [and] do not slacken.","tr":"Yusabbihoona allayla wannaharala yafturoon","juz":17,"page":323},{"s":21,"a":21,"key":"21:21","ar":"أَمِ ٱتَّخَذُوٓا۟ ءَالِهَةً مِّنَ ٱلْأَرْضِ هُمْ يُنشِرُونَ","en":"Or have they [i.e., men] taken for themselves gods from the earth who resurrect [the dead]?","tr":"Ami ittakhathoo alihatan minaal-ardi hum yunshiroon","juz":17,"page":323},{"s":21,"a":22,"key":"21:22","ar":"لَوْ كَانَ فِيهِمَآ ءَالِهَةٌ إِلَّا ٱللَّهُ لَفَسَدَتَا ۚ فَسُبْحَـٰنَ ٱللَّهِ رَبِّ ٱلْعَرْشِ عَمَّا يَصِفُونَ","en":"Had there been within them [i.e., the heavens and earth] gods besides Allāh, they both would have been ruined. So exalted is Allāh, Lord of the Throne, above what they describe.","tr":"Law kana feehima alihatunilla Allahu lafasadata fasubhana Allahirabbi alAAarshi AAamma yasifoon","juz":17,"page":323},{"s":21,"a":23,"key":"21:23","ar":"لَا يُسْـَٔلُ عَمَّا يَفْعَلُ وَهُمْ يُسْـَٔلُونَ","en":"He is not questioned about what He does, but they will be questioned.","tr":"La yus-alu AAamma yafAAaluwahum yus-aloon","juz":17,"page":323},{"s":21,"a":24,"key":"21:24","ar":"أَمِ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ ءَالِهَةً ۖ قُلْ هَاتُوا۟ بُرْهَـٰنَكُمْ ۖ هَـٰذَا ذِكْرُ مَن مَّعِىَ وَذِكْرُ مَن قَبْلِى ۗ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ ٱلْحَقَّ ۖ فَهُم مُّعْرِضُونَ","en":"Or have they taken gods besides Him? Say, [O Muḥammad], \"Produce your proof. This [Qur’ān] is the message for those with me and the message of those before me.\"1 But most of them do not know the truth, so they are turning away.","tr":"Ami ittakhathoo min doonihi alihatanqul hatoo burhanakum hatha thikru manmaAAiya wathikru man qablee bal aktharuhum layaAAlamoona alhaqqa fahum muAAridoon","juz":17,"page":323},{"s":21,"a":25,"key":"21:25","ar":"وَمَآ أَرْسَلْنَا مِن قَبْلِكَ مِن رَّسُولٍ إِلَّا نُوحِىٓ إِلَيْهِ أَنَّهُۥ لَآ إِلَـٰهَ إِلَّآ أَنَا۠ فَٱعْبُدُونِ","en":"And We sent not before you any messenger except We revealed to him that, \"There is no deity except Me, so worship Me.\"","tr":"Wama arsalna min qablika minrasoolin illa noohee ilayhi annahu la ilahailla ana faAAbudoon","juz":17,"page":324},{"s":21,"a":26,"key":"21:26","ar":"وَقَالُوا۟ ٱتَّخَذَ ٱلرَّحْمَـٰنُ وَلَدًا ۗ سُبْحَـٰنَهُۥ ۚ بَلْ عِبَادٌ مُّكْرَمُونَ","en":"And they say, \"The Most Merciful has taken a son.\" Exalted is He! Rather, they1 are [but] honored servants.","tr":"Waqaloo ittakhatha arrahmanuwaladan subhanahu bal AAibadun mukramoon","juz":17,"page":324},{"s":21,"a":27,"key":"21:27","ar":"لَا يَسْبِقُونَهُۥ بِٱلْقَوْلِ وَهُم بِأَمْرِهِۦ يَعْمَلُونَ","en":"They cannot precede Him in word, and they act by His command.","tr":"La yasbiqoonahu bilqawliwahum bi-amrihi yaAAmaloon","juz":17,"page":324},{"s":21,"a":28,"key":"21:28","ar":"يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَلَا يَشْفَعُونَ إِلَّا لِمَنِ ٱرْتَضَىٰ وَهُم مِّنْ خَشْيَتِهِۦ مُشْفِقُونَ","en":"He knows what is [presently] before them and what will be after them,1 and they cannot intercede except on behalf of one whom He approves. And they, from fear of Him, are apprehensive.","tr":"YaAAlamu ma bayna aydeehim wamakhalfahum wala yashfaAAoona illa limani irtadawahum min khashyatihi mushfiqoon","juz":17,"page":324},{"s":21,"a":29,"key":"21:29","ar":"۞ وَمَن يَقُلْ مِنْهُمْ إِنِّىٓ إِلَـٰهٌ مِّن دُونِهِۦ فَذَٰلِكَ نَجْزِيهِ جَهَنَّمَ ۚ كَذَٰلِكَ نَجْزِى ٱلظَّـٰلِمِينَ","en":"And whoever of them should say, \"Indeed, I am a god besides Him\" - that one We would recompense with Hell. Thus do We recompense the wrongdoers.","tr":"Waman yaqul minhum innee ilahun mindoonihi fathalika najzeehi jahannama kathalikanajzee aththalimeen","juz":17,"page":324},{"s":21,"a":30,"key":"21:30","ar":"أَوَلَمْ يَرَ ٱلَّذِينَ كَفَرُوٓا۟ أَنَّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ كَانَتَا رَتْقًا فَفَتَقْنَـٰهُمَا ۖ وَجَعَلْنَا مِنَ ٱلْمَآءِ كُلَّ شَىْءٍ حَىٍّ ۖ أَفَلَا يُؤْمِنُونَ","en":"Have those who disbelieved not considered that the heavens and the earth were a joined entity, and then We separated them and made from water every living thing? Then will they not believe?","tr":"Awa lam yara allatheenakafaroo anna assamawati wal-ardakanata ratqan fafataqnahuma wajaAAalnamina alma-i kulla shay-in hayyin afalayu/minoon","juz":17,"page":324},{"s":21,"a":31,"key":"21:31","ar":"وَجَعَلْنَا فِى ٱلْأَرْضِ رَوَٰسِىَ أَن تَمِيدَ بِهِمْ وَجَعَلْنَا فِيهَا فِجَاجًا سُبُلًا لَّعَلَّهُمْ يَهْتَدُونَ","en":"And We placed within the earth firmly set mountains, lest it should shift with them, and We made therein [mountain] passes [as] roads that they might be guided.","tr":"WajaAAalna fee al-ardi rawasiyaan tameeda bihim wajaAAalna feeha fijajansubulan laAAallahum yahtadoon","juz":17,"page":324},{"s":21,"a":32,"key":"21:32","ar":"وَجَعَلْنَا ٱلسَّمَآءَ سَقْفًا مَّحْفُوظًا ۖ وَهُمْ عَنْ ءَايَـٰتِهَا مُعْرِضُونَ","en":"And We made the sky a protected ceiling, but they, from its signs,1 are turning away.","tr":"WajaAAalna assamaasaqfan mahfoothan wahum AAan ayatihamuAAridoon","juz":17,"page":324},{"s":21,"a":33,"key":"21:33","ar":"وَهُوَ ٱلَّذِى خَلَقَ ٱلَّيْلَ وَٱلنَّهَارَ وَٱلشَّمْسَ وَٱلْقَمَرَ ۖ كُلٌّ فِى فَلَكٍ يَسْبَحُونَ","en":"And it is He who created the night and the day and the sun and the moon; all [heavenly bodies] in an orbit are swimming.","tr":"Wahuwa allathee khalaqa allayla wannaharawashshamsa walqamara kullun fee falakin yasbahoon","juz":17,"page":324},{"s":21,"a":34,"key":"21:34","ar":"وَمَا جَعَلْنَا لِبَشَرٍ مِّن قَبْلِكَ ٱلْخُلْدَ ۖ أَفَإِي۟ن مِّتَّ فَهُمُ ٱلْخَـٰلِدُونَ","en":"And We did not grant to any man before you eternity [on earth]; so if you die - would they be eternal?","tr":"Wama jaAAalna libasharin minqablika alkhulda afa-in mitta fahumu alkhalidoon","juz":17,"page":324},{"s":21,"a":35,"key":"21:35","ar":"كُلُّ نَفْسٍ ذَآئِقَةُ ٱلْمَوْتِ ۗ وَنَبْلُوكُم بِٱلشَّرِّ وَٱلْخَيْرِ فِتْنَةً ۖ وَإِلَيْنَا تُرْجَعُونَ","en":"Every soul will taste death. And We test you with evil and with good as trial; and to Us you will be returned.","tr":"Kullu nafsin tha-iqatu almawtiwanablookum bishsharri walkhayri fitnatanwa-ilayna turjaAAoon","juz":17,"page":324},{"s":21,"a":36,"key":"21:36","ar":"وَإِذَا رَءَاكَ ٱلَّذِينَ كَفَرُوٓا۟ إِن يَتَّخِذُونَكَ إِلَّا هُزُوًا أَهَـٰذَا ٱلَّذِى يَذْكُرُ ءَالِهَتَكُمْ وَهُم بِذِكْرِ ٱلرَّحْمَـٰنِ هُمْ كَـٰفِرُونَ","en":"And when those who disbelieve see you, [O Muḥammad], they take you not except in ridicule, [saying], \"Is this the one who mentions [i.e., insults] your gods?\" And they are, at the mention of the Most Merciful, disbelievers.","tr":"Wa-itha raaka allatheenakafaroo in yattakhithoonaka illa huzuwan ahathaallathee yathkuru alihatakum wahum bithikriarrahmani hum kafiroon","juz":17,"page":325},{"s":21,"a":37,"key":"21:37","ar":"خُلِقَ ٱلْإِنسَـٰنُ مِنْ عَجَلٍ ۚ سَأُو۟رِيكُمْ ءَايَـٰتِى فَلَا تَسْتَعْجِلُونِ","en":"Man was created of haste [i.e., impatience]. I will show you My signs [i.e., vengeance], so do not impatiently urge Me.","tr":"Khuliqa al-insanu min AAajalinsaoreekum ayatee fala tastaAAjiloon","juz":17,"page":325},{"s":21,"a":38,"key":"21:38","ar":"وَيَقُولُونَ مَتَىٰ هَـٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَ","en":"And they say, \"When is this promise, if you should be truthful?\"","tr":"Wayaqooloona mata hathaalwaAAdu in kuntum sadiqeen","juz":17,"page":325},{"s":21,"a":39,"key":"21:39","ar":"لَوْ يَعْلَمُ ٱلَّذِينَ كَفَرُوا۟ حِينَ لَا يَكُفُّونَ عَن وُجُوهِهِمُ ٱلنَّارَ وَلَا عَن ظُهُورِهِمْ وَلَا هُمْ يُنصَرُونَ","en":"If those who disbelieved but knew the time when they will not avert the Fire from their faces or from their backs and they will not be aided...1","tr":"Law yaAAlamu allatheena kafaroo heenala yakuffoona AAan wujoohihimu annara walaAAan thuhoorihim wala hum yunsaroon","juz":17,"page":325},{"s":21,"a":40,"key":"21:40","ar":"بَلْ تَأْتِيهِم بَغْتَةً فَتَبْهَتُهُمْ فَلَا يَسْتَطِيعُونَ رَدَّهَا وَلَا هُمْ يُنظَرُونَ","en":"Rather, it will come to them unexpectedly and bewilder them, and they will not be able to repel it, nor will they be reprieved.","tr":"Bal ta/teehim baghtatan fatabhatuhum falayastateeAAoona raddaha wala hum yuntharoon","juz":17,"page":325},{"s":21,"a":41,"key":"21:41","ar":"وَلَقَدِ ٱسْتُهْزِئَ بِرُسُلٍ مِّن قَبْلِكَ فَحَاقَ بِٱلَّذِينَ سَخِرُوا۟ مِنْهُم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"And already were messengers ridiculed before you, but those who mocked them were enveloped by what they used to ridicule.","tr":"Walaqadi istuhzi-a birusulin min qablika fahaqabillatheena sakhiroo minhum ma kanoobihi yastahzi-oon","juz":17,"page":325},{"s":21,"a":42,"key":"21:42","ar":"قُلْ مَن يَكْلَؤُكُم بِٱلَّيْلِ وَٱلنَّهَارِ مِنَ ٱلرَّحْمَـٰنِ ۗ بَلْ هُمْ عَن ذِكْرِ رَبِّهِم مُّعْرِضُونَ","en":"Say, \"Who can protect you at night or by day from the Most Merciful?\" But they are, from the remembrance of their Lord, turning away.","tr":"Qul man yaklaokum billayli wannaharimina arrahmani bal hum AAan thikrirabbihim muAAridoon","juz":17,"page":325},{"s":21,"a":43,"key":"21:43","ar":"أَمْ لَهُمْ ءَالِهَةٌ تَمْنَعُهُم مِّن دُونِنَا ۚ لَا يَسْتَطِيعُونَ نَصْرَ أَنفُسِهِمْ وَلَا هُم مِّنَّا يُصْحَبُونَ","en":"Or do they have gods to defend them other than Us? They are unable [even] to help themselves, nor can they be protected from Us.","tr":"Am lahum alihatun tamnaAAuhum mindoonina la yastateeAAoona nasraanfusihim wala hum minna yushaboon","juz":17,"page":325},{"s":21,"a":44,"key":"21:44","ar":"بَلْ مَتَّعْنَا هَـٰٓؤُلَآءِ وَءَابَآءَهُمْ حَتَّىٰ طَالَ عَلَيْهِمُ ٱلْعُمُرُ ۗ أَفَلَا يَرَوْنَ أَنَّا نَأْتِى ٱلْأَرْضَ نَنقُصُهَا مِنْ أَطْرَافِهَآ ۚ أَفَهُمُ ٱلْغَـٰلِبُونَ","en":"But, [on the contrary], We have provided good things for these [disbelievers] and their fathers until life was prolonged for them. Then do they not see that We set upon the land, reducing it from its borders?1 Is it they who will overcome?","tr":"Bal mattaAAna haola-iwaabaahum hatta talaAAalayhimu alAAumuru afala yarawna anna na/teeal-arda nanqusuha min atrafihaafahumu alghaliboon","juz":17,"page":325},{"s":21,"a":45,"key":"21:45","ar":"قُلْ إِنَّمَآ أُنذِرُكُم بِٱلْوَحْىِ ۚ وَلَا يَسْمَعُ ٱلصُّمُّ ٱلدُّعَآءَ إِذَا مَا يُنذَرُونَ","en":"Say, \"I only warn you by revelation.\" But the deaf do not hear the call when they are warned.","tr":"Qul innama onthirukum bilwahyiwala yasmaAAu assummu adduAAaaitha ma yuntharoon","juz":17,"page":326},{"s":21,"a":46,"key":"21:46","ar":"وَلَئِن مَّسَّتْهُمْ نَفْحَةٌ مِّنْ عَذَابِ رَبِّكَ لَيَقُولُنَّ يَـٰوَيْلَنَآ إِنَّا كُنَّا ظَـٰلِمِينَ","en":"And if [as much as] a whiff of the punishment of your Lord should touch them, they would surely say, \"O woe to us! Indeed, we have been wrongdoers.\"","tr":"Wala-in massat-hum nafhatun min AAathabirabbika layaqoolunna ya waylana inna kunnathalimeen","juz":17,"page":326},{"s":21,"a":47,"key":"21:47","ar":"وَنَضَعُ ٱلْمَوَٰزِينَ ٱلْقِسْطَ لِيَوْمِ ٱلْقِيَـٰمَةِ فَلَا تُظْلَمُ نَفْسٌ شَيْـًٔا ۖ وَإِن كَانَ مِثْقَالَ حَبَّةٍ مِّنْ خَرْدَلٍ أَتَيْنَا بِهَا ۗ وَكَفَىٰ بِنَا حَـٰسِبِينَ","en":"And We place the scales of justice for the Day of Resurrection, so no soul will be treated unjustly at all. And if there is [even] the weight of a mustard seed,1 We will bring it forth. And sufficient are We as accountant.","tr":"WanadaAAu almawazeena alqistaliyawmi alqiyamati fala tuthlamunafsun shay-an wa-in kana mithqala habbatinmin khardalin atayna biha wakafa binahasibeen","juz":17,"page":326},{"s":21,"a":48,"key":"21:48","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَىٰ وَهَـٰرُونَ ٱلْفُرْقَانَ وَضِيَآءً وَذِكْرًا لِّلْمُتَّقِينَ","en":"And We had already given Moses and Aaron the criterion and a light and a reminder1 for the righteous","tr":"Walaqad atayna moosawaharoona alfurqana wadiyaan wathikranlilmuttaqeen","juz":17,"page":326},{"s":21,"a":49,"key":"21:49","ar":"ٱلَّذِينَ يَخْشَوْنَ رَبَّهُم بِٱلْغَيْبِ وَهُم مِّنَ ٱلسَّاعَةِ مُشْفِقُونَ","en":"Who fear their Lord unseen,1 while they are of the Hour apprehensive.","tr":"Allatheena yakhshawna rabbahum bilghaybiwahum mina assaAAati mushfiqoon","juz":17,"page":326},{"s":21,"a":50,"key":"21:50","ar":"وَهَـٰذَا ذِكْرٌ مُّبَارَكٌ أَنزَلْنَـٰهُ ۚ أَفَأَنتُمْ لَهُۥ مُنكِرُونَ","en":"And this [Qur’ān] is a blessed message which We have sent down. Then are you with it unacquainted?1","tr":"Wahatha thikrun mubarakunanzalnahu afaantum lahu munkiroon","juz":17,"page":326},{"s":21,"a":51,"key":"21:51","ar":"۞ وَلَقَدْ ءَاتَيْنَآ إِبْرَٰهِيمَ رُشْدَهُۥ مِن قَبْلُ وَكُنَّا بِهِۦ عَـٰلِمِينَ","en":"And We had certainly given Abraham his sound judgement before,1 and We were of him well-Knowing","tr":"Walaqad atayna ibraheemarushdahu min qablu wakunna bihi AAalimeen","juz":17,"page":326},{"s":21,"a":52,"key":"21:52","ar":"إِذْ قَالَ لِأَبِيهِ وَقَوْمِهِۦ مَا هَـٰذِهِ ٱلتَّمَاثِيلُ ٱلَّتِىٓ أَنتُمْ لَهَا عَـٰكِفُونَ","en":"When he said to his father and his people, \"What are these statues to which you are devoted?\"","tr":"Ith qala li-abeehi waqawmihi mahathihi attamatheelu allatee antum lahaAAakifoon","juz":17,"page":326},{"s":21,"a":53,"key":"21:53","ar":"قَالُوا۟ وَجَدْنَآ ءَابَآءَنَا لَهَا عَـٰبِدِينَ","en":"They said, \"We found our fathers worshippers of them.\"","tr":"Qaloo wajadna abaanalaha AAabideen","juz":17,"page":326},{"s":21,"a":54,"key":"21:54","ar":"قَالَ لَقَدْ كُنتُمْ أَنتُمْ وَءَابَآؤُكُمْ فِى ضَلَـٰلٍ مُّبِينٍ","en":"He said, \"You were certainly, you and your fathers, in manifest error.\"","tr":"Qala laqad kuntum antum waabaokumfee dalalin mubeen","juz":17,"page":326},{"s":21,"a":55,"key":"21:55","ar":"قَالُوٓا۟ أَجِئْتَنَا بِٱلْحَقِّ أَمْ أَنتَ مِنَ ٱللَّـٰعِبِينَ","en":"They said, \"Have you come to us with truth, or are you of those who jest?\"","tr":"Qaloo aji/tana bilhaqqiam anta mina allaAAibeen","juz":17,"page":326},{"s":21,"a":56,"key":"21:56","ar":"قَالَ بَل رَّبُّكُمْ رَبُّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ٱلَّذِى فَطَرَهُنَّ وَأَنَا۠ عَلَىٰ ذَٰلِكُم مِّنَ ٱلشَّـٰهِدِينَ","en":"He said, \"[No], rather, your Lord is the Lord of the heavens and the earth who created them, and I, to that, am of those who testify.","tr":"Qala bal rabbukum rabbu assamawatiwal-ardi allathee fatarahunna waanaAAala thalikum mina ashshahideen","juz":17,"page":326},{"s":21,"a":57,"key":"21:57","ar":"وَتَٱللَّهِ لَأَكِيدَنَّ أَصْنَـٰمَكُم بَعْدَ أَن تُوَلُّوا۟ مُدْبِرِينَ","en":"And [I swear] by Allāh, I will surely plan against your idols after you have turned and gone away.\"","tr":"Watallahi laakeedanna asnamakumbaAAda an tuwalloo mudbireen","juz":17,"page":326},{"s":21,"a":58,"key":"21:58","ar":"فَجَعَلَهُمْ جُذَٰذًا إِلَّا كَبِيرًا لَّهُمْ لَعَلَّهُمْ إِلَيْهِ يَرْجِعُونَ","en":"So he made them into fragments, except a large one among them, that they might return to it [and question].","tr":"FajaAAalahum juthathan illakabeeran lahum laAAallahum ilayhi yarjiAAoon","juz":17,"page":327},{"s":21,"a":59,"key":"21:59","ar":"قَالُوا۟ مَن فَعَلَ هَـٰذَا بِـَٔالِهَتِنَآ إِنَّهُۥ لَمِنَ ٱلظَّـٰلِمِينَ","en":"They said, \"Who has done this to our gods? Indeed, he is of the wrongdoers.\"","tr":"Qaloo man faAAala hatha bi-alihatinainnahu lamina aththalimeen","juz":17,"page":327},{"s":21,"a":60,"key":"21:60","ar":"قَالُوا۟ سَمِعْنَا فَتًى يَذْكُرُهُمْ يُقَالُ لَهُۥٓ إِبْرَٰهِيمُ","en":"They said, \"We heard a young man mention them who is called Abraham.\"","tr":"Qaloo samiAAna fatan yathkuruhumyuqalu lahu ibraheem","juz":17,"page":327},{"s":21,"a":61,"key":"21:61","ar":"قَالُوا۟ فَأْتُوا۟ بِهِۦ عَلَىٰٓ أَعْيُنِ ٱلنَّاسِ لَعَلَّهُمْ يَشْهَدُونَ","en":"They said, \"Then bring him before the eyes of the people that they may testify.\"1","tr":"Qaloo fa/too bihi AAalaaAAyuni annasi laAAallahum yashhadoon","juz":17,"page":327},{"s":21,"a":62,"key":"21:62","ar":"قَالُوٓا۟ ءَأَنتَ فَعَلْتَ هَـٰذَا بِـَٔالِهَتِنَا يَـٰٓإِبْرَٰهِيمُ","en":"They said, \"Have you done this to our gods, O Abraham?\"","tr":"Qaloo aanta faAAalta hatha bi-alihatinaya ibraheem","juz":17,"page":327},{"s":21,"a":63,"key":"21:63","ar":"قَالَ بَلْ فَعَلَهُۥ كَبِيرُهُمْ هَـٰذَا فَسْـَٔلُوهُمْ إِن كَانُوا۟ يَنطِقُونَ","en":"He said, \"Rather, this - the largest of them - did it, so ask them, if they should [be able to] speak.\"","tr":"Qala bal faAAalahu kabeeruhum hathafas-aloohum in kanoo yantiqoon","juz":17,"page":327},{"s":21,"a":64,"key":"21:64","ar":"فَرَجَعُوٓا۟ إِلَىٰٓ أَنفُسِهِمْ فَقَالُوٓا۟ إِنَّكُمْ أَنتُمُ ٱلظَّـٰلِمُونَ","en":"So they returned to [blaming] themselves and said [to each other], \"Indeed, you are the wrongdoers.\"","tr":"FarajaAAoo ila anfusihim faqalooinnakum antumu aththalimoon","juz":17,"page":327},{"s":21,"a":65,"key":"21:65","ar":"ثُمَّ نُكِسُوا۟ عَلَىٰ رُءُوسِهِمْ لَقَدْ عَلِمْتَ مَا هَـٰٓؤُلَآءِ يَنطِقُونَ","en":"Then they reversed themselves,1 [saying], \"You have already known that these do not speak!\"","tr":"Thumma nukisoo AAala ruoosihim laqadAAalimta ma haola-i yantiqoon","juz":17,"page":327},{"s":21,"a":66,"key":"21:66","ar":"قَالَ أَفَتَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُكُمْ شَيْـًٔا وَلَا يَضُرُّكُمْ","en":"He said, \"Then do you worship instead of Allāh that which does not benefit you at all or harm you?","tr":"Qala afataAAbudoona min dooni Allahima la yanfaAAukum shay-an wala yadurrukum","juz":17,"page":327},{"s":21,"a":67,"key":"21:67","ar":"أُفٍّ لَّكُمْ وَلِمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ ۖ أَفَلَا تَعْقِلُونَ","en":"Uff1 to you and to what you worship instead of Allāh. Then will you not use reason?\"","tr":"Offin lakum walima taAAbudoona mindooni Allahi afala taAAqiloon","juz":17,"page":327},{"s":21,"a":68,"key":"21:68","ar":"قَالُوا۟ حَرِّقُوهُ وَٱنصُرُوٓا۟ ءَالِهَتَكُمْ إِن كُنتُمْ فَـٰعِلِينَ","en":"They said, \"Burn him and support your gods - if you are to act.\"","tr":"Qaloo harriqoohu wansurooalihatakum in kuntum faAAileen","juz":17,"page":327},{"s":21,"a":69,"key":"21:69","ar":"قُلْنَا يَـٰنَارُ كُونِى بَرْدًا وَسَلَـٰمًا عَلَىٰٓ إِبْرَٰهِيمَ","en":"We [i.e., Allāh] said, \"O fire, be coolness and safety upon Abraham.\"","tr":"Qulna ya naru kooneebardan wasalaman AAala ibraheem","juz":17,"page":327},{"s":21,"a":70,"key":"21:70","ar":"وَأَرَادُوا۟ بِهِۦ كَيْدًا فَجَعَلْنَـٰهُمُ ٱلْأَخْسَرِينَ","en":"And they intended for him a plan [i.e., harm], but We made them the greatest losers.","tr":"Waaradoo bihi kaydan fajaAAalnahumual-akhsareen","juz":17,"page":327},{"s":21,"a":71,"key":"21:71","ar":"وَنَجَّيْنَـٰهُ وَلُوطًا إِلَى ٱلْأَرْضِ ٱلَّتِى بَـٰرَكْنَا فِيهَا لِلْعَـٰلَمِينَ","en":"And We delivered him and Lot to the land which We had blessed for the worlds [i.e., peoples].","tr":"Wanajjaynahu walootan ilaal-ardi allatee barakna feeha lilAAalameen","juz":17,"page":327},{"s":21,"a":72,"key":"21:72","ar":"وَوَهَبْنَا لَهُۥٓ إِسْحَـٰقَ وَيَعْقُوبَ نَافِلَةً ۖ وَكُلًّا جَعَلْنَا صَـٰلِحِينَ","en":"And We gave him Isaac and Jacob in addition, and all [of them] We made righteous.","tr":"Wawahabna lahu ishaqawayaAAqooba nafilatan wakullan jaAAalna saliheen","juz":17,"page":327},{"s":21,"a":73,"key":"21:73","ar":"وَجَعَلْنَـٰهُمْ أَئِمَّةً يَهْدُونَ بِأَمْرِنَا وَأَوْحَيْنَآ إِلَيْهِمْ فِعْلَ ٱلْخَيْرَٰتِ وَإِقَامَ ٱلصَّلَوٰةِ وَإِيتَآءَ ٱلزَّكَوٰةِ ۖ وَكَانُوا۟ لَنَا عَـٰبِدِينَ","en":"And We made them leaders guiding by Our command. And We inspired to them the doing of good deeds, establishment of prayer, and giving of zakāh; and they were worshippers of Us.","tr":"WajaAAalnahum a-immatan yahdoonabi-amrina waawhayna ilayhim fiAAla alkhayratiwa-iqama assalati wa-eetaa azzakatiwakanoo lana AAabideen","juz":17,"page":328},{"s":21,"a":74,"key":"21:74","ar":"وَلُوطًا ءَاتَيْنَـٰهُ حُكْمًا وَعِلْمًا وَنَجَّيْنَـٰهُ مِنَ ٱلْقَرْيَةِ ٱلَّتِى كَانَت تَّعْمَلُ ٱلْخَبَـٰٓئِثَ ۗ إِنَّهُمْ كَانُوا۟ قَوْمَ سَوْءٍ فَـٰسِقِينَ","en":"And to Lot We gave judgement and knowledge, and We saved him from the city that was committing wicked deeds. Indeed, they were a people of evil, defiantly disobedient.","tr":"Walootan ataynahu hukmanwaAAilman wanajjaynahu mina alqaryati allatee kanattaAAmalu alkhaba-itha innahum kanoo qawma saw-in fasiqeen","juz":17,"page":328},{"s":21,"a":75,"key":"21:75","ar":"وَأَدْخَلْنَـٰهُ فِى رَحْمَتِنَآ ۖ إِنَّهُۥ مِنَ ٱلصَّـٰلِحِينَ","en":"And We admitted him into Our mercy. Indeed, he was of the righteous.","tr":"Waadkhalnahu fee rahmatinainnahu mina assaliheen","juz":17,"page":328},{"s":21,"a":76,"key":"21:76","ar":"وَنُوحًا إِذْ نَادَىٰ مِن قَبْلُ فَٱسْتَجَبْنَا لَهُۥ فَنَجَّيْنَـٰهُ وَأَهْلَهُۥ مِنَ ٱلْكَرْبِ ٱلْعَظِيمِ","en":"And [mention] Noah, when he called [to Allāh]1 before [that time], so We responded to him and saved him and his family from the great affliction [i.e., the flood].","tr":"Wanoohan ith nadamin qablu fastajabna lahu fanajjaynahuwaahlahu mina alkarbi alAAatheem","juz":17,"page":328},{"s":21,"a":77,"key":"21:77","ar":"وَنَصَرْنَـٰهُ مِنَ ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَآ ۚ إِنَّهُمْ كَانُوا۟ قَوْمَ سَوْءٍ فَأَغْرَقْنَـٰهُمْ أَجْمَعِينَ","en":"And We aided [i.e., saved] him from the people who denied Our signs. Indeed, they were a people of evil, so We drowned them, all together.","tr":"Wanasarnahu mina alqawmi allatheenakaththaboo bi-ayatina innahum kanooqawma saw-in faaghraqnahum ajmaAAeen","juz":17,"page":328},{"s":21,"a":78,"key":"21:78","ar":"وَدَاوُۥدَ وَسُلَيْمَـٰنَ إِذْ يَحْكُمَانِ فِى ٱلْحَرْثِ إِذْ نَفَشَتْ فِيهِ غَنَمُ ٱلْقَوْمِ وَكُنَّا لِحُكْمِهِمْ شَـٰهِدِينَ","en":"And [mention] David and Solomon, when they judged concerning the field - when the sheep of a people overran it [at night],1 and We were witness to their judgement.","tr":"Wadawooda wasulaymana ithyahkumani fee alharthi ith nafashatfeehi ghanamu alqawmi wakunna lihukmihim shahideen","juz":17,"page":328},{"s":21,"a":79,"key":"21:79","ar":"فَفَهَّمْنَـٰهَا سُلَيْمَـٰنَ ۚ وَكُلًّا ءَاتَيْنَا حُكْمًا وَعِلْمًا ۚ وَسَخَّرْنَا مَعَ دَاوُۥدَ ٱلْجِبَالَ يُسَبِّحْنَ وَٱلطَّيْرَ ۚ وَكُنَّا فَـٰعِلِينَ","en":"And We gave understanding of it [i.e., the case] to Solomon, and to each [of them] We gave judgement and knowledge. And We subjected the mountains to exalt [Us], along with David and [also] the birds. And We were doing [that].1","tr":"Fafahhamnaha sulaymanawakullan atayna hukman waAAilman wasakhkharnamaAAa dawooda aljibala yusabbihna wattayrawakunna faAAileen","juz":17,"page":328},{"s":21,"a":80,"key":"21:80","ar":"وَعَلَّمْنَـٰهُ صَنْعَةَ لَبُوسٍ لَّكُمْ لِتُحْصِنَكُم مِّنۢ بَأْسِكُمْ ۖ فَهَلْ أَنتُمْ شَـٰكِرُونَ","en":"And We taught him the fashioning of coats of armor to protect you from your [enemy in] battle. So will you then be grateful?","tr":"WaAAallamnahu sanAAatalaboosin lakum lituhsinakum min ba/sikum fahal antum shakiroon","juz":17,"page":328},{"s":21,"a":81,"key":"21:81","ar":"وَلِسُلَيْمَـٰنَ ٱلرِّيحَ عَاصِفَةً تَجْرِى بِأَمْرِهِۦٓ إِلَى ٱلْأَرْضِ ٱلَّتِى بَـٰرَكْنَا فِيهَا ۚ وَكُنَّا بِكُلِّ شَىْءٍ عَـٰلِمِينَ","en":"And to Solomon [We subjected] the wind, blowing forcefully, proceeding by his command toward the land which We had blessed. And We are ever, of all things, Knowing.","tr":"Walisulaymana arreehaAAasifatan tajree bi-amrihi ila al-ardiallatee barakna feeha wakunna bikullishay-in AAalimeen","juz":17,"page":328},{"s":21,"a":82,"key":"21:82","ar":"وَمِنَ ٱلشَّيَـٰطِينِ مَن يَغُوصُونَ لَهُۥ وَيَعْمَلُونَ عَمَلًا دُونَ ذَٰلِكَ ۖ وَكُنَّا لَهُمْ حَـٰفِظِينَ","en":"And of the devils [i.e., jinn] were those who dived for him and did work other than that. And We were of them a guardian.1","tr":"Wamina ashshayateeni manyaghoosoona lahu wayaAAmaloona AAamalan doona thalikawakunna lahum hafitheen","juz":17,"page":329},{"s":21,"a":83,"key":"21:83","ar":"۞ وَأَيُّوبَ إِذْ نَادَىٰ رَبَّهُۥٓ أَنِّى مَسَّنِىَ ٱلضُّرُّ وَأَنتَ أَرْحَمُ ٱلرَّٰحِمِينَ","en":"And [mention] Job, when he called to his Lord, \"Indeed, adversity has touched me, and You are the most merciful of the merciful.\"","tr":"Waayyooba ith nadarabbahu annee massaniya addurru waanta arhamuarrahimeen","juz":17,"page":329},{"s":21,"a":84,"key":"21:84","ar":"فَٱسْتَجَبْنَا لَهُۥ فَكَشَفْنَا مَا بِهِۦ مِن ضُرٍّ ۖ وَءَاتَيْنَـٰهُ أَهْلَهُۥ وَمِثْلَهُم مَّعَهُمْ رَحْمَةً مِّنْ عِندِنَا وَذِكْرَىٰ لِلْعَـٰبِدِينَ","en":"So We responded to him and removed what afflicted him of adversity. And We gave him [back] his family and the like thereof with them as mercy from Us and a reminder for the worshippers [of Allāh].","tr":"Fastajabna lahu fakashafnama bihi min durrin waataynahu ahlahuwamithlahum maAAahum rahmatan min AAindina wathikralilAAabideen","juz":17,"page":329},{"s":21,"a":85,"key":"21:85","ar":"وَإِسْمَـٰعِيلَ وَإِدْرِيسَ وَذَا ٱلْكِفْلِ ۖ كُلٌّ مِّنَ ٱلصَّـٰبِرِينَ","en":"And [mention] Ishmael and Idrees and Dhul-Kifl; all were of the patient.","tr":"Wa-ismaAAeela wa-idreesa wathaalkifli kullun mina assabireen","juz":17,"page":329},{"s":21,"a":86,"key":"21:86","ar":"وَأَدْخَلْنَـٰهُمْ فِى رَحْمَتِنَآ ۖ إِنَّهُم مِّنَ ٱلصَّـٰلِحِينَ","en":"And We admitted them into Our mercy. Indeed, they were of the righteous.","tr":"Waadkhalnahum fee rahmatinainnahum mina assaliheen","juz":17,"page":329},{"s":21,"a":87,"key":"21:87","ar":"وَذَا ٱلنُّونِ إِذ ذَّهَبَ مُغَـٰضِبًا فَظَنَّ أَن لَّن نَّقْدِرَ عَلَيْهِ فَنَادَىٰ فِى ٱلظُّلُمَـٰتِ أَن لَّآ إِلَـٰهَ إِلَّآ أَنتَ سُبْحَـٰنَكَ إِنِّى كُنتُ مِنَ ٱلظَّـٰلِمِينَ","en":"And [mention] the man of the fish [i.e., Jonah], when he went off in anger1 and thought that We would not decree [anything] upon him.2 And he called out within the darknesses,3 \"There is no deity except You; exalted are You. Indeed, I have been of the wrongdoers.\"","tr":"Watha annooni ith thahabamughadiban fathanna an lan naqdira AAalayhifanada fee aththulumatian la ilaha illa anta subhanaka inneekuntu mina aththalimeen","juz":17,"page":329},{"s":21,"a":88,"key":"21:88","ar":"فَٱسْتَجَبْنَا لَهُۥ وَنَجَّيْنَـٰهُ مِنَ ٱلْغَمِّ ۚ وَكَذَٰلِكَ نُـۨجِى ٱلْمُؤْمِنِينَ","en":"So We responded to him and saved him from the distress. And thus do We save the believers.","tr":"Fastajabna lahu wanajjaynahumina alghammi wakathalika nunjee almu/mineen","juz":17,"page":329},{"s":21,"a":89,"key":"21:89","ar":"وَزَكَرِيَّآ إِذْ نَادَىٰ رَبَّهُۥ رَبِّ لَا تَذَرْنِى فَرْدًا وَأَنتَ خَيْرُ ٱلْوَٰرِثِينَ","en":"And [mention] Zechariah, when he called to his Lord, \"My Lord, do not leave me alone [with no heir], while You are the best of inheritors.\"","tr":"Wazakariyya ith nadarabbahu rabbi la tatharnee fardan waanta khayru alwaritheen","juz":17,"page":329},{"s":21,"a":90,"key":"21:90","ar":"فَٱسْتَجَبْنَا لَهُۥ وَوَهَبْنَا لَهُۥ يَحْيَىٰ وَأَصْلَحْنَا لَهُۥ زَوْجَهُۥٓ ۚ إِنَّهُمْ كَانُوا۟ يُسَـٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَيَدْعُونَنَا رَغَبًا وَرَهَبًا ۖ وَكَانُوا۟ لَنَا خَـٰشِعِينَ","en":"So We responded to him, and We gave to him John, and amended for him his wife. Indeed, they used to hasten to good deeds and supplicate1 Us in hope and fear, and they were to Us humbly submissive.","tr":"Fastajabna lahu wawahabnalahu yahya waaslahna lahuzawjahu innahum kanoo yusariAAoona fee alkhayratiwayadAAoonana raghaban warahaban wakanoo lanakhashiAAeen","juz":17,"page":329},{"s":21,"a":91,"key":"21:91","ar":"وَٱلَّتِىٓ أَحْصَنَتْ فَرْجَهَا فَنَفَخْنَا فِيهَا مِن رُّوحِنَا وَجَعَلْنَـٰهَا وَٱبْنَهَآ ءَايَةً لِّلْعَـٰلَمِينَ","en":"And [mention] the one who guarded her chastity [i.e., Mary], so We blew into her [garment] through Our angel [i.e., Gabriel], and We made her and her son a sign for the worlds.","tr":"Wallatee ahsanat farjahafanafakhna feeha min roohinawajaAAalnaha wabnaha ayatanlilAAalameen","juz":17,"page":330},{"s":21,"a":92,"key":"21:92","ar":"إِنَّ هَـٰذِهِۦٓ أُمَّتُكُمْ أُمَّةً وَٰحِدَةً وَأَنَا۠ رَبُّكُمْ فَٱعْبُدُونِ","en":"Indeed this, your religion, is one religion,1 and I am your Lord, so worship Me.","tr":"Inna hathihi ommatukum ommatan wahidatanwaana rabbukum faoAAbudoon","juz":17,"page":330},{"s":21,"a":93,"key":"21:93","ar":"وَتَقَطَّعُوٓا۟ أَمْرَهُم بَيْنَهُمْ ۖ كُلٌّ إِلَيْنَا رَٰجِعُونَ","en":"And [yet] they divided their affair [i.e., that of their religion] among themselves,1 [but] all to Us will return.","tr":"WataqattaAAoo amrahum baynahum kullunilayna rajiAAoon","juz":17,"page":330},{"s":21,"a":94,"key":"21:94","ar":"فَمَن يَعْمَلْ مِنَ ٱلصَّـٰلِحَـٰتِ وَهُوَ مُؤْمِنٌ فَلَا كُفْرَانَ لِسَعْيِهِۦ وَإِنَّا لَهُۥ كَـٰتِبُونَ","en":"So whoever does righteous deeds while he is a believer - no denial will there be for his effort,1 and indeed We [i.e., Our angels], of it, are recorders.","tr":"Faman yaAAmal mina assalihatiwahuwa mu/minun fala kufrana lisaAAyihi wa-innalahu katiboon","juz":17,"page":330},{"s":21,"a":95,"key":"21:95","ar":"وَحَرَٰمٌ عَلَىٰ قَرْيَةٍ أَهْلَكْنَـٰهَآ أَنَّهُمْ لَا يَرْجِعُونَ","en":"And it is prohibited to [the people of] a city which We have destroyed that they will [ever] return1","tr":"Waharamun AAalaqaryatin ahlaknaha annahum la yarjiAAoon","juz":17,"page":330},{"s":21,"a":96,"key":"21:96","ar":"حَتَّىٰٓ إِذَا فُتِحَتْ يَأْجُوجُ وَمَأْجُوجُ وَهُم مِّن كُلِّ حَدَبٍ يَنسِلُونَ","en":"Until when [the dam of] Gog and Magog has been opened and they, from every elevation, descend","tr":"Hatta itha futihatya/jooju wama/jooju wahum min kulli hadabin yansiloon","juz":17,"page":330},{"s":21,"a":97,"key":"21:97","ar":"وَٱقْتَرَبَ ٱلْوَعْدُ ٱلْحَقُّ فَإِذَا هِىَ شَـٰخِصَةٌ أَبْصَـٰرُ ٱلَّذِينَ كَفَرُوا۟ يَـٰوَيْلَنَا قَدْ كُنَّا فِى غَفْلَةٍ مِّنْ هَـٰذَا بَلْ كُنَّا ظَـٰلِمِينَ","en":"And [when] the true promise [i.e., the resurrection] has approached; then suddenly the eyes of those who disbelieved will be staring [in horror, while they say], \"O woe to us; we had been unmindful of this; rather, we were wrongdoers.\"","tr":"Waqtaraba alwaAAdu alhaqqufa-itha hiya shakhisatun absaru allatheenakafaroo ya waylana qad kunna fee ghaflatinmin hatha bal kunna thalimeen","juz":17,"page":330},{"s":21,"a":98,"key":"21:98","ar":"إِنَّكُمْ وَمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ حَصَبُ جَهَنَّمَ أَنتُمْ لَهَا وَٰرِدُونَ","en":"Indeed, you [disbelievers] and what you worship other than Allāh are the firewood of Hell. You will be coming to [enter] it.","tr":"Innakum wama taAAbudoona min dooniAllahi hasabu jahannama antum laha waridoon","juz":17,"page":330},{"s":21,"a":99,"key":"21:99","ar":"لَوْ كَانَ هَـٰٓؤُلَآءِ ءَالِهَةً مَّا وَرَدُوهَا ۖ وَكُلٌّ فِيهَا خَـٰلِدُونَ","en":"Had these [false deities] been [actual] gods, they would not have come to it, but all are eternal therein.","tr":"Law kana haola-i alihatanma waradooha wakullun feeha khalidoon","juz":17,"page":330},{"s":21,"a":100,"key":"21:100","ar":"لَهُمْ فِيهَا زَفِيرٌ وَهُمْ فِيهَا لَا يَسْمَعُونَ","en":"For them therein is heavy sighing, and they therein will not hear.","tr":"Lahum feeha zafeerun wahum feehala yasmaAAoon","juz":17,"page":330},{"s":21,"a":101,"key":"21:101","ar":"إِنَّ ٱلَّذِينَ سَبَقَتْ لَهُم مِّنَّا ٱلْحُسْنَىٰٓ أُو۟لَـٰٓئِكَ عَنْهَا مُبْعَدُونَ","en":"Indeed, those for whom the best [reward] has preceded from Us - they are from it far removed.","tr":"Inna allatheena sabaqat lahum minnaalhusna ola-ika AAanha mubAAadoon","juz":17,"page":330},{"s":21,"a":102,"key":"21:102","ar":"لَا يَسْمَعُونَ حَسِيسَهَا ۖ وَهُمْ فِى مَا ٱشْتَهَتْ أَنفُسُهُمْ خَـٰلِدُونَ","en":"They will not hear its sound, while they are, in that which their souls desire, abiding eternally.","tr":"La yasmaAAoona haseesahawahum fee ma ishtahat anfusuhum khalidoon","juz":17,"page":331},{"s":21,"a":103,"key":"21:103","ar":"لَا يَحْزُنُهُمُ ٱلْفَزَعُ ٱلْأَكْبَرُ وَتَتَلَقَّىٰهُمُ ٱلْمَلَـٰٓئِكَةُ هَـٰذَا يَوْمُكُمُ ٱلَّذِى كُنتُمْ تُوعَدُونَ","en":"They will not be grieved by the greatest terror,1 and the angels will meet them, [saying], \"This is your Day which you have been promised\" -","tr":"La yahzunuhumu alfazaAAual-akbaru watatalaqqahumu almala-ikatu hathayawmukumu allathee kuntum tooAAadoon","juz":17,"page":331},{"s":21,"a":104,"key":"21:104","ar":"يَوْمَ نَطْوِى ٱلسَّمَآءَ كَطَىِّ ٱلسِّجِلِّ لِلْكُتُبِ ۚ كَمَا بَدَأْنَآ أَوَّلَ خَلْقٍ نُّعِيدُهُۥ ۚ وَعْدًا عَلَيْنَآ ۚ إِنَّا كُنَّا فَـٰعِلِينَ","en":"The Day when We will fold the heaven like the folding of a [written] sheet for the records. As We began the first creation, We will repeat it. [That is] a promise binding upon Us. Indeed, We will do it.1","tr":"Yawma natwee assamaakatayyi assijlli lilkutubi kama bada/naawwala khalqin nuAAeeduhu waAAdan AAalayna innakunna faAAileen","juz":17,"page":331},{"s":21,"a":105,"key":"21:105","ar":"وَلَقَدْ كَتَبْنَا فِى ٱلزَّبُورِ مِنۢ بَعْدِ ٱلذِّكْرِ أَنَّ ٱلْأَرْضَ يَرِثُهَا عِبَادِىَ ٱلصَّـٰلِحُونَ","en":"And We have already written in the book [of Psalms]1 after the [previous] mention2 that the land [of Paradise] is inherited by My righteous servants.","tr":"Walaqad katabna fee azzaboorimin baAAdi aththikri anna al-arda yarithuhaAAibadiya assalihoon","juz":17,"page":331},{"s":21,"a":106,"key":"21:106","ar":"إِنَّ فِى هَـٰذَا لَبَلَـٰغًا لِّقَوْمٍ عَـٰبِدِينَ","en":"Indeed, in this [Qur’ān] is notification for a worshipping people.","tr":"Inna fee hatha labalaghanliqawmin AAabideen","juz":17,"page":331},{"s":21,"a":107,"key":"21:107","ar":"وَمَآ أَرْسَلْنَـٰكَ إِلَّا رَحْمَةً لِّلْعَـٰلَمِينَ","en":"And We have not sent you, [O Muḥammad], except as a mercy to the worlds.","tr":"Wama arsalnaka illa rahmatanlilAAalameen","juz":17,"page":331},{"s":21,"a":108,"key":"21:108","ar":"قُلْ إِنَّمَا يُوحَىٰٓ إِلَىَّ أَنَّمَآ إِلَـٰهُكُمْ إِلَـٰهٌ وَٰحِدٌ ۖ فَهَلْ أَنتُم مُّسْلِمُونَ","en":"Say, \"It is only revealed to me that your god is but one God; so will you be Muslims [in submission to Him]?\"","tr":"Qul innama yooha ilayya annamailahukum ilahun wahidun fahal antummuslimoon","juz":17,"page":331},{"s":21,"a":109,"key":"21:109","ar":"فَإِن تَوَلَّوْا۟ فَقُلْ ءَاذَنتُكُمْ عَلَىٰ سَوَآءٍ ۖ وَإِنْ أَدْرِىٓ أَقَرِيبٌ أَم بَعِيدٌ مَّا تُوعَدُونَ","en":"But if they turn away, then say, \"I have announced to [all of] you equally.1 And I know not whether near or far is that which you are promised.","tr":"Fa-in tawallaw faqul athantukum AAalasawa-in wa-in adree aqareebun am baAAeedun matooAAadoon","juz":17,"page":331},{"s":21,"a":110,"key":"21:110","ar":"إِنَّهُۥ يَعْلَمُ ٱلْجَهْرَ مِنَ ٱلْقَوْلِ وَيَعْلَمُ مَا تَكْتُمُونَ","en":"Indeed, He knows what is declared of speech, and He knows what you conceal.","tr":"Innahu yaAAlamu aljahra mina alqawliwayaAAlamu ma taktumoon","juz":17,"page":331},{"s":21,"a":111,"key":"21:111","ar":"وَإِنْ أَدْرِى لَعَلَّهُۥ فِتْنَةٌ لَّكُمْ وَمَتَـٰعٌ إِلَىٰ حِينٍ","en":"And I know not; perhaps it1 is a trial for you and enjoyment for a time.\"","tr":"Wa-in adree laAAallahu fitnatun lakum wamataAAunila heen","juz":17,"page":331},{"s":21,"a":112,"key":"21:112","ar":"قَـٰلَ رَبِّ ٱحْكُم بِٱلْحَقِّ ۗ وَرَبُّنَا ٱلرَّحْمَـٰنُ ٱلْمُسْتَعَانُ عَلَىٰ مَا تَصِفُونَ","en":"[The Prophet (ﷺ)] has said, \"My Lord, judge [between us] in truth. And our Lord is the Most Merciful, the one whose help is sought against that which you describe.\"1","tr":"Qala rabbi ohkum bilhaqqiwarabbuna arrahmanu almustaAAanuAAala ma tasifoon","juz":17,"page":331},{"s":22,"a":1,"key":"22:1","ar":" يَـٰٓأَيُّهَا ٱلنَّاسُ ٱتَّقُوا۟ رَبَّكُمْ ۚ إِنَّ زَلْزَلَةَ ٱلسَّاعَةِ شَىْءٌ عَظِيمٌ","en":"O mankind, fear your Lord. Indeed, the convulsion of the [final] Hour is a terrible thing.","tr":"Ya ayyuha annasuittaqoo rabbakum inna zalzalata assaAAati shay-onAAatheem","juz":17,"page":332},{"s":22,"a":2,"key":"22:2","ar":"يَوْمَ تَرَوْنَهَا تَذْهَلُ كُلُّ مُرْضِعَةٍ عَمَّآ أَرْضَعَتْ وَتَضَعُ كُلُّ ذَاتِ حَمْلٍ حَمْلَهَا وَتَرَى ٱلنَّاسَ سُكَـٰرَىٰ وَمَا هُم بِسُكَـٰرَىٰ وَلَـٰكِنَّ عَذَابَ ٱللَّهِ شَدِيدٌ","en":"On the Day you see it every nursing mother will be distracted from that [child] she was nursing, and every pregnant woman will abort her pregnancy, and you will see the people [appearing] intoxicated while they are not intoxicated; but the punishment of Allāh is severe.","tr":"Yawma tarawnaha tathhalu kullumurdiAAatin AAamma ardaAAat watadaAAukullu thati hamlin hamlaha wataraannasa sukara wama hum bisukarawalakinna AAathaba Allahi shadeed","juz":17,"page":332},{"s":22,"a":3,"key":"22:3","ar":"وَمِنَ ٱلنَّاسِ مَن يُجَـٰدِلُ فِى ٱللَّهِ بِغَيْرِ عِلْمٍ وَيَتَّبِعُ كُلَّ شَيْطَـٰنٍ مَّرِيدٍ","en":"And of the people is he who disputes about Allāh without knowledge and follows every rebellious devil.","tr":"Wamina annasi man yujadilufee Allahi bighayri AAilmin wayattabiAAu kulla shaytaninmareed","juz":17,"page":332},{"s":22,"a":4,"key":"22:4","ar":"كُتِبَ عَلَيْهِ أَنَّهُۥ مَن تَوَلَّاهُ فَأَنَّهُۥ يُضِلُّهُۥ وَيَهْدِيهِ إِلَىٰ عَذَابِ ٱلسَّعِيرِ","en":"It has been decreed for him [i.e., every devil] that whoever turns to him - he will misguide him and will lead him to the punishment of the Blaze.","tr":"Kutiba AAalayhi annahu man tawallahufaannahu yudilluhu wayahdeehi ila AAathabi assaAAeer","juz":17,"page":332},{"s":22,"a":5,"key":"22:5","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ إِن كُنتُمْ فِى رَيْبٍ مِّنَ ٱلْبَعْثِ فَإِنَّا خَلَقْنَـٰكُم مِّن تُرَابٍ ثُمَّ مِن نُّطْفَةٍ ثُمَّ مِنْ عَلَقَةٍ ثُمَّ مِن مُّضْغَةٍ مُّخَلَّقَةٍ وَغَيْرِ مُخَلَّقَةٍ لِّنُبَيِّنَ لَكُمْ ۚ وَنُقِرُّ فِى ٱلْأَرْحَامِ مَا نَشَآءُ إِلَىٰٓ أَجَلٍ مُّسَمًّى ثُمَّ نُخْرِجُكُمْ طِفْلًا ثُمَّ لِتَبْلُغُوٓا۟ أَشُدَّكُمْ ۖ وَمِنكُم مَّن يُتَوَفَّىٰ وَمِنكُم مَّن يُرَدُّ إِلَىٰٓ أَرْذَلِ ٱلْعُمُرِ لِكَيْلَا يَعْلَمَ مِنۢ بَعْدِ عِلْمٍ شَيْـًٔا ۚ وَتَرَى ٱلْأَرْضَ هَامِدَةً فَإِذَآ أَنزَلْنَا عَلَيْهَا ٱلْمَآءَ ٱهْتَزَّتْ وَرَبَتْ وَأَنۢبَتَتْ مِن كُلِّ زَوْجٍۭ بَهِيجٍ","en":"O people, if you should be in doubt about the Resurrection, then [consider that] indeed, We created you from dust, then from a sperm-drop, then from a clinging clot, and then from a lump of flesh, formed and unformed1 - that We may show you.2 And We settle in the wombs whom We will for a specified term, then We bring you out as a child, and then [We develop you] that you may reach your [time of] maturity. And among you is he who is taken in [early] death, and among you is he who is returned to the most decrepit [old] age so that he knows, after [once having] knowledge, nothing. And you see the earth barren, but when We send down upon it rain, it quivers and swells and grows [something] of every beautiful kind.","tr":"Ya ayyuha annasuin kuntum fee raybin mina albaAAthi fa-inna khalaqnakummin turabin thumma min nutfatin thumma minAAalaqatin thumma min mudghatin mukhallaqatin waghayrimukhallaqatin linubayyina lakum wanuqirru fee al-arhami manashao ila ajalin musamman thumma nukhrijukum tiflanthumma litablughoo ashuddakum waminkum man yutawaffawaminkum man yuraddu ila arthali alAAumuri likaylayaAAlama min baAAdi AAilmin shay-an watara al-ardahamidatan fa-itha anzalna AAalayhaalmaa ihtazzat warabat waanbatat min kulli zawjin baheej","juz":17,"page":332},{"s":22,"a":6,"key":"22:6","ar":"ذَٰلِكَ بِأَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ وَأَنَّهُۥ يُحْىِ ٱلْمَوْتَىٰ وَأَنَّهُۥ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"That is because Allāh is the True Reality and because He gives life to the dead and because He is over all things competent","tr":"Thalika bi-anna Allaha huwa alhaqquwaannahu yuhyee almawta waannahu AAala kullishay-in qadeer","juz":17,"page":333},{"s":22,"a":7,"key":"22:7","ar":"وَأَنَّ ٱلسَّاعَةَ ءَاتِيَةٌ لَّا رَيْبَ فِيهَا وَأَنَّ ٱللَّهَ يَبْعَثُ مَن فِى ٱلْقُبُورِ","en":"And [that they may know] that the Hour is coming - no doubt about it - and that Allāh will resurrect those in the graves.","tr":"Waanna assaAAata atiyatunla rayba feeha waanna Allaha yabAAathu manfee alquboor","juz":17,"page":333},{"s":22,"a":8,"key":"22:8","ar":"وَمِنَ ٱلنَّاسِ مَن يُجَـٰدِلُ فِى ٱللَّهِ بِغَيْرِ عِلْمٍ وَلَا هُدًى وَلَا كِتَـٰبٍ مُّنِيرٍ","en":"And of the people is he who disputes about Allāh without knowledge or guidance or an enlightening book [from Him],","tr":"Wamina annasi man yujadilufee Allahi bighayri AAilmin wala hudan walakitabin muneer","juz":17,"page":333},{"s":22,"a":9,"key":"22:9","ar":"ثَانِىَ عِطْفِهِۦ لِيُضِلَّ عَن سَبِيلِ ٱللَّهِ ۖ لَهُۥ فِى ٱلدُّنْيَا خِزْىٌ ۖ وَنُذِيقُهُۥ يَوْمَ ٱلْقِيَـٰمَةِ عَذَابَ ٱلْحَرِيقِ","en":"Twisting his neck [in arrogance] to mislead [people] from the way of Allāh. For him in the world is disgrace, and We will make him taste on the Day of Resurrection the punishment of the Burning Fire [while it is said],","tr":"Thaniya AAitfihi liyudillaAAan sabeeli Allahi lahu fee addunyakhizyun wanutheequhu yawma alqiyamati AAathabaalhareeq","juz":17,"page":333},{"s":22,"a":10,"key":"22:10","ar":"ذَٰلِكَ بِمَا قَدَّمَتْ يَدَاكَ وَأَنَّ ٱللَّهَ لَيْسَ بِظَلَّـٰمٍ لِّلْعَبِيدِ","en":"\"That is for what your hands have put forth and because Allāh is not ever unjust to [His] servants.\"","tr":"Thalika bima qaddamat yadakawaanna Allaha laysa bithallaminlilAAabeed","juz":17,"page":333},{"s":22,"a":11,"key":"22:11","ar":"وَمِنَ ٱلنَّاسِ مَن يَعْبُدُ ٱللَّهَ عَلَىٰ حَرْفٍ ۖ فَإِنْ أَصَابَهُۥ خَيْرٌ ٱطْمَأَنَّ بِهِۦ ۖ وَإِنْ أَصَابَتْهُ فِتْنَةٌ ٱنقَلَبَ عَلَىٰ وَجْهِهِۦ خَسِرَ ٱلدُّنْيَا وَٱلْـَٔاخِرَةَ ۚ ذَٰلِكَ هُوَ ٱلْخُسْرَانُ ٱلْمُبِينُ","en":"And of the people is he who worships Allāh on an edge.1 If he is touched by good, he is reassured by it; but if he is struck by trial, he turns on his face [to unbelief]. He has lost [this] world and the Hereafter. That is what is the manifest loss.","tr":"Wamina annasi man yaAAbuduAllaha AAala harfin fa-in asabahukhayrun itmaanna bihi wa-in asabat-hu fitnatuninqalaba AAala wajhihi khasira addunya wal-akhiratathalika huwa alkhusranu almubeen","juz":17,"page":333},{"s":22,"a":12,"key":"22:12","ar":"يَدْعُوا۟ مِن دُونِ ٱللَّهِ مَا لَا يَضُرُّهُۥ وَمَا لَا يَنفَعُهُۥ ۚ ذَٰلِكَ هُوَ ٱلضَّلَـٰلُ ٱلْبَعِيدُ","en":"He invokes instead of Allāh that which neither harms him nor benefits him. That is what is the extreme error.","tr":"YadAAoo min dooni Allahi ma layadurruhu wama la yanfaAAuhu thalikahuwa addalalu albaAAeed","juz":17,"page":333},{"s":22,"a":13,"key":"22:13","ar":"يَدْعُوا۟ لَمَن ضَرُّهُۥٓ أَقْرَبُ مِن نَّفْعِهِۦ ۚ لَبِئْسَ ٱلْمَوْلَىٰ وَلَبِئْسَ ٱلْعَشِيرُ","en":"He invokes one whose harm is closer than his benefit - how wretched the protector and how wretched the associate.","tr":"YadAAoo laman darruhu aqrabu minnafAAihi labi/sa almawla walabi/sa alAAasheer","juz":17,"page":333},{"s":22,"a":14,"key":"22:14","ar":"إِنَّ ٱللَّهَ يُدْخِلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ۚ إِنَّ ٱللَّهَ يَفْعَلُ مَا يُرِيدُ","en":"Indeed, Allāh will admit those who believe and do righteous deeds to gardens beneath which rivers flow. Indeed, Allāh does what He intends.","tr":"Inna Allaha yudkhilu allatheenaamanoo waAAamiloo assalihati jannatintajree min tahtiha al-anharu inna AllahayafAAalu ma yureed","juz":17,"page":333},{"s":22,"a":15,"key":"22:15","ar":"مَن كَانَ يَظُنُّ أَن لَّن يَنصُرَهُ ٱللَّهُ فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ فَلْيَمْدُدْ بِسَبَبٍ إِلَى ٱلسَّمَآءِ ثُمَّ لْيَقْطَعْ فَلْيَنظُرْ هَلْ يُذْهِبَنَّ كَيْدُهُۥ مَا يَغِيظُ","en":"Whoever should think that Allāh will not support him [i.e., Prophet Muḥammad (ﷺ)] in this world and the Hereafter - let him extend a rope to the ceiling, then cut off [his breath],1 and let him see: will his effort remove that which enrages [him]?","tr":"Man kana yathunnu anlan yansurahu Allahu fee addunya wal-akhiratifalyamdud bisababin ila assama-i thummaliyaqtaAA falyanthur hal yuthhibannakayduhu ma yagheeth","juz":17,"page":333},{"s":22,"a":16,"key":"22:16","ar":"وَكَذَٰلِكَ أَنزَلْنَـٰهُ ءَايَـٰتٍۭ بَيِّنَـٰتٍ وَأَنَّ ٱللَّهَ يَهْدِى مَن يُرِيدُ","en":"And thus have We sent it [i.e., the Qur’ān] down as verses of clear evidence and because Allāh guides whom He intends.","tr":"Wakathalika anzalnahu ayatinbayyinatin waanna Allaha yahdee man yureed","juz":17,"page":334},{"s":22,"a":17,"key":"22:17","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَٱلَّذِينَ هَادُوا۟ وَٱلصَّـٰبِـِٔينَ وَٱلنَّصَـٰرَىٰ وَٱلْمَجُوسَ وَٱلَّذِينَ أَشْرَكُوٓا۟ إِنَّ ٱللَّهَ يَفْصِلُ بَيْنَهُمْ يَوْمَ ٱلْقِيَـٰمَةِ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ شَهِيدٌ","en":"Indeed, those who have believed and those who were Jews and the Sabeans and the Christians and the Magians and those who associated with Allāh - Allāh will judge between them on the Day of Resurrection. Indeed Allāh is, over all things, Witness.1","tr":"Inna allatheena amanoo wallatheenahadoo wassabi-eena wannasarawalmajoosa wallatheena ashrakoo inna Allahayafsilu baynahum yawma alqiyamati inna AllahaAAala kulli shay-in shaheed","juz":17,"page":334},{"s":22,"a":18,"key":"22:18","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ يَسْجُدُ لَهُۥ مَن فِى ٱلسَّمَـٰوَٰتِ وَمَن فِى ٱلْأَرْضِ وَٱلشَّمْسُ وَٱلْقَمَرُ وَٱلنُّجُومُ وَٱلْجِبَالُ وَٱلشَّجَرُ وَٱلدَّوَآبُّ وَكَثِيرٌ مِّنَ ٱلنَّاسِ ۖ وَكَثِيرٌ حَقَّ عَلَيْهِ ٱلْعَذَابُ ۗ وَمَن يُهِنِ ٱللَّهُ فَمَا لَهُۥ مِن مُّكْرِمٍ ۚ إِنَّ ٱللَّهَ يَفْعَلُ مَا يَشَآءُ ۩","en":"Do you not see [i.e., know] that to Allāh prostrates whoever is in the heavens and whoever is on the earth and the sun, the moon, the stars, the mountains, the trees, the moving creatures and many of the people? But upon many the punishment has been justified.1 And he whom Allāh humiliates - for him there is no bestower of honor. Indeed, Allāh does what He wills.","tr":"Alam tara anna Allaha yasjudu lahuman fee assamawati waman fee al-ardiwashshamsu walqamaru wannujoomu waljibaluwashshajaru waddawabbu wakatheerun minaannasi wakatheerun haqqa AAalayhi alAAathabuwaman yuhini Allahu fama lahu min mukrimin inna AllahayafAAalu ma yasha/","juz":17,"page":334},{"s":22,"a":19,"key":"22:19","ar":"۞ هَـٰذَانِ خَصْمَانِ ٱخْتَصَمُوا۟ فِى رَبِّهِمْ ۖ فَٱلَّذِينَ كَفَرُوا۟ قُطِّعَتْ لَهُمْ ثِيَابٌ مِّن نَّارٍ يُصَبُّ مِن فَوْقِ رُءُوسِهِمُ ٱلْحَمِيمُ","en":"These1 are two adversaries who have disputed over their Lord. But those who disbelieved will have cut out for them garments of fire. Poured upon their heads will be scalding water","tr":"Hathani khasmani ikhtasamoofee rabbihim fallatheena kafaroo quttiAAatlahum thiyabun min narin yusabbu min fawqiruoosihimu alhameem","juz":17,"page":334},{"s":22,"a":20,"key":"22:20","ar":"يُصْهَرُ بِهِۦ مَا فِى بُطُونِهِمْ وَٱلْجُلُودُ","en":"By which is melted that within their bellies and [their] skins.","tr":"Yusharu bihi ma fee butoonihimwaljulood","juz":17,"page":334},{"s":22,"a":21,"key":"22:21","ar":"وَلَهُم مَّقَـٰمِعُ مِنْ حَدِيدٍ","en":"And for [striking] them are maces of iron.","tr":"Walahum maqamiAAu min hadeed","juz":17,"page":334},{"s":22,"a":22,"key":"22:22","ar":"كُلَّمَآ أَرَادُوٓا۟ أَن يَخْرُجُوا۟ مِنْهَا مِنْ غَمٍّ أُعِيدُوا۟ فِيهَا وَذُوقُوا۟ عَذَابَ ٱلْحَرِيقِ","en":"Every time they want to get out of it [i.e., Hellfire] from anguish, they will be returned to it, and [it will be said], \"Taste the punishment of the Burning Fire!\"","tr":"Kullama aradoo an yakhrujoominha min ghammin oAAeedoo feeha wathooqooAAathaba alhareeq","juz":17,"page":334},{"s":22,"a":23,"key":"22:23","ar":"إِنَّ ٱللَّهَ يُدْخِلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ يُحَلَّوْنَ فِيهَا مِنْ أَسَاوِرَ مِن ذَهَبٍ وَلُؤْلُؤًا ۖ وَلِبَاسُهُمْ فِيهَا حَرِيرٌ","en":"Indeed, Allāh will admit those who believe and do righteous deeds to gardens beneath which rivers flow. They will be adorned therein with bracelets of gold and pearl, and their garments therein will be silk.","tr":"Inna Allaha yudkhilu allatheenaamanoo waAAamiloo assalihati jannatintajree min tahtiha al-anharu yuhallawnafeeha min asawira min thahabin walu/lu-anwalibasuhum feeha hareer","juz":17,"page":334},{"s":22,"a":24,"key":"22:24","ar":"وَهُدُوٓا۟ إِلَى ٱلطَّيِّبِ مِنَ ٱلْقَوْلِ وَهُدُوٓا۟ إِلَىٰ صِرَٰطِ ٱلْحَمِيدِ","en":"And they had been guided [in worldly life] to good speech, and they were guided to the path of the Praiseworthy.","tr":"Wahudoo ila attayyibimina alqawli wahudoo ila sirati alhameed","juz":17,"page":335},{"s":22,"a":25,"key":"22:25","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَيَصُدُّونَ عَن سَبِيلِ ٱللَّهِ وَٱلْمَسْجِدِ ٱلْحَرَامِ ٱلَّذِى جَعَلْنَـٰهُ لِلنَّاسِ سَوَآءً ٱلْعَـٰكِفُ فِيهِ وَٱلْبَادِ ۚ وَمَن يُرِدْ فِيهِ بِإِلْحَادٍۭ بِظُلْمٍ نُّذِقْهُ مِنْ عَذَابٍ أَلِيمٍ","en":"Indeed, those who have disbelieved and avert [people] from the way of Allāh and [from] al-Masjid al-Ḥarām, which We made for the people - equal are the resident therein and one from outside - and [also] whoever intends [a deed] therein1 of deviation [in religion] by wrongdoing - We will make him taste of a painful punishment.","tr":"Inna allatheena kafaroo wayasuddoonaAAan sabeeli Allahi walmasjidi alharamiallathee jaAAalnahu linnasi sawaanalAAakifu feehi walbadi waman yurid feehibi-ilhadin bithulmin nuthiqhu min AAathabinaleem","juz":17,"page":335},{"s":22,"a":26,"key":"22:26","ar":"وَإِذْ بَوَّأْنَا لِإِبْرَٰهِيمَ مَكَانَ ٱلْبَيْتِ أَن لَّا تُشْرِكْ بِى شَيْـًٔا وَطَهِّرْ بَيْتِىَ لِلطَّآئِفِينَ وَٱلْقَآئِمِينَ وَٱلرُّكَّعِ ٱلسُّجُودِ","en":"And [mention, O Muḥammad], when We designated for Abraham the site of the House, [saying], \"Do not associate anything with Me and purify My House for those who perform ṭawāf1 and those who stand [in prayer] and those who bow and prostrate.","tr":"Wa-ith bawwa/na li-ibraheemamakana albayti an la tushrik bee shay-an watahhirbaytiya litta-ifeena walqa-imeenawarrukkaAAi assujood","juz":17,"page":335},{"s":22,"a":27,"key":"22:27","ar":"وَأَذِّن فِى ٱلنَّاسِ بِٱلْحَجِّ يَأْتُوكَ رِجَالًا وَعَلَىٰ كُلِّ ضَامِرٍ يَأْتِينَ مِن كُلِّ فَجٍّ عَمِيقٍ","en":"And proclaim to the people the ḥajj [pilgrimage]; they will come to you on foot and on every lean camel; they will come from every distant pass -","tr":"Waaththin fee annasibilhajji ya/tooka rijalan waAAalakulli damirin ya/teena min kulli fajjin AAameeq","juz":17,"page":335},{"s":22,"a":28,"key":"22:28","ar":"لِّيَشْهَدُوا۟ مَنَـٰفِعَ لَهُمْ وَيَذْكُرُوا۟ ٱسْمَ ٱللَّهِ فِىٓ أَيَّامٍ مَّعْلُومَـٰتٍ عَلَىٰ مَا رَزَقَهُم مِّنۢ بَهِيمَةِ ٱلْأَنْعَـٰمِ ۖ فَكُلُوا۟ مِنْهَا وَأَطْعِمُوا۟ ٱلْبَآئِسَ ٱلْفَقِيرَ","en":"That they may witness [i.e., attend] benefits for themselves and mention the name of Allāh on known [i.e., specific] days over what He has provided for them of [sacrificial] animals.1 So eat of them and feed the miserable and poor.","tr":"Liyashhadoo manafiAAa lahum wayathkurooisma Allahi fee ayyamin maAAloomatin AAalama razaqahum min baheemati al-anAAami fakuloo minhawaatAAimoo alba-isa alfaqeer","juz":17,"page":335},{"s":22,"a":29,"key":"22:29","ar":"ثُمَّ لْيَقْضُوا۟ تَفَثَهُمْ وَلْيُوفُوا۟ نُذُورَهُمْ وَلْيَطَّوَّفُوا۟ بِٱلْبَيْتِ ٱلْعَتِيقِ","en":"Then let them end their untidiness and fulfill their vows and perform ṭawāf around the ancient House.\"","tr":"Thumma lyaqdoo tafathahum walyoofoonuthoorahum walyattawwafoo bilbaytialAAateeq","juz":17,"page":335},{"s":22,"a":30,"key":"22:30","ar":"ذَٰلِكَ وَمَن يُعَظِّمْ حُرُمَـٰتِ ٱللَّهِ فَهُوَ خَيْرٌ لَّهُۥ عِندَ رَبِّهِۦ ۗ وَأُحِلَّتْ لَكُمُ ٱلْأَنْعَـٰمُ إِلَّا مَا يُتْلَىٰ عَلَيْكُمْ ۖ فَٱجْتَنِبُوا۟ ٱلرِّجْسَ مِنَ ٱلْأَوْثَـٰنِ وَٱجْتَنِبُوا۟ قَوْلَ ٱلزُّورِ","en":"That [has been commanded], and whoever honors the sacred ordinances of Allāh - it is best for him in the sight of his Lord. And permitted to you are the grazing livestock, except what is recited to you.1 So avoid the uncleanliness of idols and avoid false statement,","tr":"Thalika waman yuAAaththimhurumati Allahi fahuwa khayrun lahu AAindarabbihi waohillat lakumu al-anAAamu illa mayutla AAalaykum fajtaniboo arrijsa minaal-awthani wajtaniboo qawla azzoor","juz":17,"page":335},{"s":22,"a":31,"key":"22:31","ar":"حُنَفَآءَ لِلَّهِ غَيْرَ مُشْرِكِينَ بِهِۦ ۚ وَمَن يُشْرِكْ بِٱللَّهِ فَكَأَنَّمَا خَرَّ مِنَ ٱلسَّمَآءِ فَتَخْطَفُهُ ٱلطَّيْرُ أَوْ تَهْوِى بِهِ ٱلرِّيحُ فِى مَكَانٍ سَحِيقٍ","en":"Inclining [only] to Allāh, not associating [anything] with Him. And he who associates with Allāh - it is as though he had fallen from the sky and was snatched by the birds or the wind carried him down into a remote place.","tr":"Hunafaa lillahi ghayramushrikeena bihi waman yushrik billahi fakaannamakharra mina assama-i fatakhtafuhu attayruaw tahwee bihi arreehu fee makanin saheeq","juz":17,"page":336},{"s":22,"a":32,"key":"22:32","ar":"ذَٰلِكَ وَمَن يُعَظِّمْ شَعَـٰٓئِرَ ٱللَّهِ فَإِنَّهَا مِن تَقْوَى ٱلْقُلُوبِ","en":"That [is so]. And whoever honors the symbols [i.e., rites] of Allāh - indeed, it is from the piety of hearts.","tr":"Thalika waman yuAAaththimshaAAa-ira Allahi fa-innaha min taqwaalquloob","juz":17,"page":336},{"s":22,"a":33,"key":"22:33","ar":"لَكُمْ فِيهَا مَنَـٰفِعُ إِلَىٰٓ أَجَلٍ مُّسَمًّى ثُمَّ مَحِلُّهَآ إِلَى ٱلْبَيْتِ ٱلْعَتِيقِ","en":"For you therein [i.e., the animals marked for sacrifice] are benefits for a specified term;1 then their place of sacrifice is at the ancient House.2","tr":"Lakum feeha manafiAAu ilaajalin musamman thumma mahilluha ila albaytialAAateeq","juz":17,"page":336},{"s":22,"a":34,"key":"22:34","ar":"وَلِكُلِّ أُمَّةٍ جَعَلْنَا مَنسَكًا لِّيَذْكُرُوا۟ ٱسْمَ ٱللَّهِ عَلَىٰ مَا رَزَقَهُم مِّنۢ بَهِيمَةِ ٱلْأَنْعَـٰمِ ۗ فَإِلَـٰهُكُمْ إِلَـٰهٌ وَٰحِدٌ فَلَهُۥٓ أَسْلِمُوا۟ ۗ وَبَشِّرِ ٱلْمُخْبِتِينَ","en":"And for every [religious] community We have appointed a rite [of sacrifice]1 that they may mention the name of Allāh over what He has provided for them of [sacrificial] animals. For your god is one God, so to Him submit. And, [O Muḥammad], give good tidings to the humble [before their Lord]","tr":"Walikulli ommatin jaAAalna mansakanliyathkuroo isma Allahi AAala marazaqahum min baheemati al-anAAami fa-ilahukum ilahunwahidun falahu aslimoo wabashshiri almukhbiteen","juz":17,"page":336},{"s":22,"a":35,"key":"22:35","ar":"ٱلَّذِينَ إِذَا ذُكِرَ ٱللَّهُ وَجِلَتْ قُلُوبُهُمْ وَٱلصَّـٰبِرِينَ عَلَىٰ مَآ أَصَابَهُمْ وَٱلْمُقِيمِى ٱلصَّلَوٰةِ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَ","en":"Who, when Allāh is mentioned, their hearts are fearful, and [to] the patient over what has afflicted them, and the establishers of prayer and those who spend from what We have provided them.","tr":"Allatheena itha thukiraAllahu wajilat quloobuhum wassabireenaAAala ma asabahum walmuqeemee assalatiwamimma razaqnahum yunfiqoon","juz":17,"page":336},{"s":22,"a":36,"key":"22:36","ar":"وَٱلْبُدْنَ جَعَلْنَـٰهَا لَكُم مِّن شَعَـٰٓئِرِ ٱللَّهِ لَكُمْ فِيهَا خَيْرٌ ۖ فَٱذْكُرُوا۟ ٱسْمَ ٱللَّهِ عَلَيْهَا صَوَآفَّ ۖ فَإِذَا وَجَبَتْ جُنُوبُهَا فَكُلُوا۟ مِنْهَا وَأَطْعِمُوا۟ ٱلْقَانِعَ وَٱلْمُعْتَرَّ ۚ كَذَٰلِكَ سَخَّرْنَـٰهَا لَكُمْ لَعَلَّكُمْ تَشْكُرُونَ","en":"And the camels and cattle We have appointed for you as among the symbols [i.e., rites] of Allāh; for you therein is good. So mention the name of Allāh upon them when lined up [for sacrifice]; and when they are [lifeless] on their sides, then eat from them and feed the needy [who does not seek aid] and the beggar. Thus have We subjected them to you that you may be grateful.","tr":"Walbudna jaAAalnahalakum min shaAAa-iri Allahi lakum feehakhayrun fathkuroo isma Allahi AAalayhasawaffa fa-itha wajabat junoobuhafakuloo minha waatAAimoo alqaniAAa walmuAAtarrakathalika sakhkharnaha lakum laAAallakumtashkuroon","juz":17,"page":336},{"s":22,"a":37,"key":"22:37","ar":"لَن يَنَالَ ٱللَّهَ لُحُومُهَا وَلَا دِمَآؤُهَا وَلَـٰكِن يَنَالُهُ ٱلتَّقْوَىٰ مِنكُمْ ۚ كَذَٰلِكَ سَخَّرَهَا لَكُمْ لِتُكَبِّرُوا۟ ٱللَّهَ عَلَىٰ مَا هَدَىٰكُمْ ۗ وَبَشِّرِ ٱلْمُحْسِنِينَ","en":"Their meat will not reach Allāh, nor will their blood, but what reaches Him is piety from you. Thus have We subjected them to you that you may glorify Allāh for that [to] which He has guided you; and give good tidings to the doers of good.","tr":"Lan yanala Allaha luhoomuhawala dimaoha walakin yanaluhuattaqwa minkum kathalika sakhkharahalakum litukabbiroo Allaha AAala ma hadakumwabashshiri almuhsineen","juz":17,"page":336},{"s":22,"a":38,"key":"22:38","ar":"۞ إِنَّ ٱللَّهَ يُدَٰفِعُ عَنِ ٱلَّذِينَ ءَامَنُوٓا۟ ۗ إِنَّ ٱللَّهَ لَا يُحِبُّ كُلَّ خَوَّانٍ كَفُورٍ","en":"Indeed, Allāh defends those who have believed. Indeed, Allāh does not like everyone treacherous and ungrateful.","tr":"Inna Allaha yudafiAAu AAaniallatheena amanoo inna Allaha la yuhibbukulla khawwanin kafoor","juz":17,"page":336},{"s":22,"a":39,"key":"22:39","ar":"أُذِنَ لِلَّذِينَ يُقَـٰتَلُونَ بِأَنَّهُمْ ظُلِمُوا۟ ۚ وَإِنَّ ٱللَّهَ عَلَىٰ نَصْرِهِمْ لَقَدِيرٌ","en":"Permission [to fight] has been given to those who are being fought,1 because they were wronged. And indeed, Allāh is competent to give them victory.","tr":"Othina lillatheena yuqataloonabi-annahum thulimoo wa-inna Allaha AAalanasrihim laqadeer","juz":17,"page":337},{"s":22,"a":40,"key":"22:40","ar":"ٱلَّذِينَ أُخْرِجُوا۟ مِن دِيَـٰرِهِم بِغَيْرِ حَقٍّ إِلَّآ أَن يَقُولُوا۟ رَبُّنَا ٱللَّهُ ۗ وَلَوْلَا دَفْعُ ٱللَّهِ ٱلنَّاسَ بَعْضَهُم بِبَعْضٍ لَّهُدِّمَتْ صَوَٰمِعُ وَبِيَعٌ وَصَلَوَٰتٌ وَمَسَـٰجِدُ يُذْكَرُ فِيهَا ٱسْمُ ٱللَّهِ كَثِيرًا ۗ وَلَيَنصُرَنَّ ٱللَّهُ مَن يَنصُرُهُۥٓ ۗ إِنَّ ٱللَّهَ لَقَوِىٌّ عَزِيزٌ","en":"[They are] those who have been evicted from their homes without right - only because they say, \"Our Lord is Allāh.\" And were it not that Allāh checks the people, some by means of others, there would have been demolished monasteries, churches, synagogues, and mosques in which the name of Allāh is much mentioned [i.e., praised]. And Allāh will surely support those who support Him [i.e., His cause]. Indeed, Allāh is Powerful and Exalted in Might.","tr":"Allatheena okhrijoo min diyarihimbighayri haqqin illa an yaqooloo rabbuna Allahuwalawla dafAAu Allahi annasa baAAdahumbibaAAdin lahuddimat sawamiAAu wabiyaAAun wasalawatunwamasajidu yuthkaru feeha ismu Allahikatheeran walayansuranna Allahu man yansuruhuinna Allaha laqawiyyun AAazeez","juz":17,"page":337},{"s":22,"a":41,"key":"22:41","ar":"ٱلَّذِينَ إِن مَّكَّنَّـٰهُمْ فِى ٱلْأَرْضِ أَقَامُوا۟ ٱلصَّلَوٰةَ وَءَاتَوُا۟ ٱلزَّكَوٰةَ وَأَمَرُوا۟ بِٱلْمَعْرُوفِ وَنَهَوْا۟ عَنِ ٱلْمُنكَرِ ۗ وَلِلَّهِ عَـٰقِبَةُ ٱلْأُمُورِ","en":"[And they are] those who, if We give them authority in the land, establish prayer and give zakāh and enjoin what is right and forbid what is wrong. And to Allāh belongs the outcome of [all] matters.","tr":"Allatheena in makkannahum feeal-ardi aqamoo assalata waatawooazzakata waamaroo bilmaAAroofi wanahawAAani almunkari walillahi AAaqibatu al-omoor","juz":17,"page":337},{"s":22,"a":42,"key":"22:42","ar":"وَإِن يُكَذِّبُوكَ فَقَدْ كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍ وَعَادٌ وَثَمُودُ","en":"And if they deny you, [O Muḥammad] - so, before them, did the people of Noah and ʿAad and Thamūd deny [their prophets],","tr":"Wa-in yukaththibooka faqad kaththabatqablahum qawmu noohin waAAadun wathamood","juz":17,"page":337},{"s":22,"a":43,"key":"22:43","ar":"وَقَوْمُ إِبْرَٰهِيمَ وَقَوْمُ لُوطٍ","en":"And the people of Abraham and the people of Lot.","tr":"Waqawmu ibraheema waqawmu loot","juz":17,"page":337},{"s":22,"a":44,"key":"22:44","ar":"وَأَصْحَـٰبُ مَدْيَنَ ۖ وَكُذِّبَ مُوسَىٰ فَأَمْلَيْتُ لِلْكَـٰفِرِينَ ثُمَّ أَخَذْتُهُمْ ۖ فَكَيْفَ كَانَ نَكِيرِ","en":"And the inhabitants of Madyan. And Moses was denied, so I prolonged enjoyment for the disbelievers; then I seized them, and how [terrible] was My reproach.","tr":"Waas-habu madyana wakuththibamoosa faamlaytu lilkafireena thumma akhathtuhumfakayfa kana nakeer","juz":17,"page":337},{"s":22,"a":45,"key":"22:45","ar":"فَكَأَيِّن مِّن قَرْيَةٍ أَهْلَكْنَـٰهَا وَهِىَ ظَالِمَةٌ فَهِىَ خَاوِيَةٌ عَلَىٰ عُرُوشِهَا وَبِئْرٍ مُّعَطَّلَةٍ وَقَصْرٍ مَّشِيدٍ","en":"And how many a city did We destroy while it was committing wrong - so it is [now] fallen into ruin1 - and [how many] an abandoned well and [how many] a lofty palace.2","tr":"Fakaayyin min qaryatin ahlaknahawahiya thalimatun fahiya khawiyatunAAala AAurooshiha wabi/rin muAAattalatinwaqasrin masheed","juz":17,"page":337},{"s":22,"a":46,"key":"22:46","ar":"أَفَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَتَكُونَ لَهُمْ قُلُوبٌ يَعْقِلُونَ بِهَآ أَوْ ءَاذَانٌ يَسْمَعُونَ بِهَا ۖ فَإِنَّهَا لَا تَعْمَى ٱلْأَبْصَـٰرُ وَلَـٰكِن تَعْمَى ٱلْقُلُوبُ ٱلَّتِى فِى ٱلصُّدُورِ","en":"So have they not traveled through the earth and have hearts by which to reason and ears by which to hear? For indeed, it is not eyes that are blinded, but blinded are the hearts which are within the breasts.","tr":"Afalam yaseeroo fee al-ardi fatakoonalahum quloobun yaAAqiloona biha aw athanunyasmaAAoona biha fa-innaha la taAAmaal-absaru walakin taAAma alquloobu allateefee assudoor","juz":17,"page":337},{"s":22,"a":47,"key":"22:47","ar":"وَيَسْتَعْجِلُونَكَ بِٱلْعَذَابِ وَلَن يُخْلِفَ ٱللَّهُ وَعْدَهُۥ ۚ وَإِنَّ يَوْمًا عِندَ رَبِّكَ كَأَلْفِ سَنَةٍ مِّمَّا تَعُدُّونَ","en":"And they urge you to hasten the punishment. But Allāh will never fail in His promise. And indeed, a day with your Lord is like a thousand years of those which you count.","tr":"WayastaAAjiloonaka bilAAathabiwalan yukhlifa Allahu waAAdahu wa-inna yawman AAindarabbika kaalfi sanatin mimma taAAuddoon","juz":17,"page":338},{"s":22,"a":48,"key":"22:48","ar":"وَكَأَيِّن مِّن قَرْيَةٍ أَمْلَيْتُ لَهَا وَهِىَ ظَالِمَةٌ ثُمَّ أَخَذْتُهَا وَإِلَىَّ ٱلْمَصِيرُ","en":"And for how many a city did I prolong enjoyment while it was committing wrong. Then I seized it, and to Me is the [final] destination.","tr":"Wakaayyin min qaryatin amlaytu lahawahiya thalimatun thumma akhathtuhawa-ilayya almaseer","juz":17,"page":338},{"s":22,"a":49,"key":"22:49","ar":"قُلْ يَـٰٓأَيُّهَا ٱلنَّاسُ إِنَّمَآ أَنَا۠ لَكُمْ نَذِيرٌ مُّبِينٌ","en":"Say, \"O people, I am only to you a clear warner.\"","tr":"Qul ya ayyuha annasuinnama ana lakum natheerun mubeen","juz":17,"page":338},{"s":22,"a":50,"key":"22:50","ar":"فَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَهُم مَّغْفِرَةٌ وَرِزْقٌ كَرِيمٌ","en":"And those who have believed and done righteous deeds - for them is forgiveness and noble provision.","tr":"Fallatheena amanoowaAAamiloo assalihati lahum maghfiratunwarizqun kareem","juz":17,"page":338},{"s":22,"a":51,"key":"22:51","ar":"وَٱلَّذِينَ سَعَوْا۟ فِىٓ ءَايَـٰتِنَا مُعَـٰجِزِينَ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْجَحِيمِ","en":"But the ones who strove against Our verses, [seeking] to cause failure1 - those are the companions of Hellfire.","tr":"Wallatheena saAAaw fee ayatinamuAAajizeena ola-ika as-habu aljaheem","juz":17,"page":338},{"s":22,"a":52,"key":"22:52","ar":"وَمَآ أَرْسَلْنَا مِن قَبْلِكَ مِن رَّسُولٍ وَلَا نَبِىٍّ إِلَّآ إِذَا تَمَنَّىٰٓ أَلْقَى ٱلشَّيْطَـٰنُ فِىٓ أُمْنِيَّتِهِۦ فَيَنسَخُ ٱللَّهُ مَا يُلْقِى ٱلشَّيْطَـٰنُ ثُمَّ يُحْكِمُ ٱللَّهُ ءَايَـٰتِهِۦ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"And We did not send before you any messenger or prophet except that when he spoke [or recited], Satan threw into it [some misunderstanding]. But Allāh abolishes that which Satan throws in; then Allāh makes precise His verses.1 And Allāh is Knowing and Wise.","tr":"Wama arsalna min qablika minrasoolin wala nabiyyin illa itha tamannaalqa ashshaytanu fee omniyyatihi fayansakhuAllahu ma yulqee ashshaytanu thummayuhkimu Allahu ayatihi wallahuAAaleemun hakeem","juz":17,"page":338},{"s":22,"a":53,"key":"22:53","ar":"لِّيَجْعَلَ مَا يُلْقِى ٱلشَّيْطَـٰنُ فِتْنَةً لِّلَّذِينَ فِى قُلُوبِهِم مَّرَضٌ وَٱلْقَاسِيَةِ قُلُوبُهُمْ ۗ وَإِنَّ ٱلظَّـٰلِمِينَ لَفِى شِقَاقٍۭ بَعِيدٍ","en":"[That is] so He may make what Satan throws in [i.e., asserts] a trial for those within whose hearts is disease1 and those hard of heart. And indeed, the wrongdoers are in extreme dissension.","tr":"LiyajAAala ma yulqee ashshaytanufitnatan lillatheena fee quloobihim maradun walqasiyatiquloobuhum wa-inna aththalimeenalafee shiqaqin baAAeed","juz":17,"page":338},{"s":22,"a":54,"key":"22:54","ar":"وَلِيَعْلَمَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ أَنَّهُ ٱلْحَقُّ مِن رَّبِّكَ فَيُؤْمِنُوا۟ بِهِۦ فَتُخْبِتَ لَهُۥ قُلُوبُهُمْ ۗ وَإِنَّ ٱللَّهَ لَهَادِ ٱلَّذِينَ ءَامَنُوٓا۟ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"And so those who were given knowledge may know that it is the truth from your Lord and [therefore] believe in it, and their hearts humbly submit to it. And indeed is Allāh the Guide of those who have believed to a straight path.","tr":"WaliyaAAlama allatheena ootooalAAilma annahu alhaqqu min rabbika fayu/minoo bihifatukhbita lahu quloobuhum wa-inna Allaha lahadiallatheena amanoo ila siratinmustaqeem","juz":17,"page":338},{"s":22,"a":55,"key":"22:55","ar":"وَلَا يَزَالُ ٱلَّذِينَ كَفَرُوا۟ فِى مِرْيَةٍ مِّنْهُ حَتَّىٰ تَأْتِيَهُمُ ٱلسَّاعَةُ بَغْتَةً أَوْ يَأْتِيَهُمْ عَذَابُ يَوْمٍ عَقِيمٍ","en":"But those who disbelieve will not cease to be in doubt of it until the Hour comes upon them unexpectedly or there comes to them the punishment of a barren Day.1","tr":"Wala yazalu allatheenakafaroo fee miryatin minhu hatta ta/tiyahumu assaAAatubaghtatan aw ya/tiyahum AAathabu yawmin AAaqeem","juz":17,"page":338},{"s":22,"a":56,"key":"22:56","ar":"ٱلْمُلْكُ يَوْمَئِذٍ لِّلَّهِ يَحْكُمُ بَيْنَهُمْ ۚ فَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ فِى جَنَّـٰتِ ٱلنَّعِيمِ","en":"[All] sovereignty that Day is for Allāh;1 He will judge between them. So they who believed and did righteous deeds will be in the Gardens of Pleasure.","tr":"Almulku yawma-ithin lillahi yahkumubaynahum fallatheena amanoo waAAamiloo assalihatifee jannati annaAAeem","juz":17,"page":339},{"s":22,"a":57,"key":"22:57","ar":"وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَـٰتِنَا فَأُو۟لَـٰٓئِكَ لَهُمْ عَذَابٌ مُّهِينٌ","en":"And they who disbelieved and denied Our signs - for those there will be a humiliating punishment.","tr":"Wallatheena kafaroo wakaththaboobi-ayatina faola-ika lahum AAathabunmuheen","juz":17,"page":339},{"s":22,"a":58,"key":"22:58","ar":"وَٱلَّذِينَ هَاجَرُوا۟ فِى سَبِيلِ ٱللَّهِ ثُمَّ قُتِلُوٓا۟ أَوْ مَاتُوا۟ لَيَرْزُقَنَّهُمُ ٱللَّهُ رِزْقًا حَسَنًا ۚ وَإِنَّ ٱللَّهَ لَهُوَ خَيْرُ ٱلرَّٰزِقِينَ","en":"And those who emigrated for the cause of Allāh and then were killed or died - Allāh will surely provide for them a good provision. And indeed, it is Allāh who is the best of providers.","tr":"Wallatheena hajaroofee sabeeli Allahi thumma qutiloo aw matoolayarzuqannahumu Allahu rizqan hasanan wa-inna Allahalahuwa khayru arraziqeen","juz":17,"page":339},{"s":22,"a":59,"key":"22:59","ar":"لَيُدْخِلَنَّهُم مُّدْخَلًا يَرْضَوْنَهُۥ ۗ وَإِنَّ ٱللَّهَ لَعَلِيمٌ حَلِيمٌ","en":"He will surely cause them to enter an entrance with which they will be pleased, and indeed, Allāh is Knowing and Forbearing.","tr":"Layudkhilannahum mudkhalan yardawnahuwa-inna Allaha laAAaleemun haleem","juz":17,"page":339},{"s":22,"a":60,"key":"22:60","ar":"۞ ذَٰلِكَ وَمَنْ عَاقَبَ بِمِثْلِ مَا عُوقِبَ بِهِۦ ثُمَّ بُغِىَ عَلَيْهِ لَيَنصُرَنَّهُ ٱللَّهُ ۗ إِنَّ ٱللَّهَ لَعَفُوٌّ غَفُورٌ","en":"That [is so]. And whoever responds [to injustice] with the equivalent of that with which he was harmed and then is tyrannized - Allāh will surely aid him. Indeed, Allāh is Pardoning and Forgiving.1","tr":"Thalika waman AAaqaba bimithlima AAooqiba bihi thumma bughiya AAalayhi layansurannahuAllahu inna Allaha laAAafuwwun ghafoor","juz":17,"page":339},{"s":22,"a":61,"key":"22:61","ar":"ذَٰلِكَ بِأَنَّ ٱللَّهَ يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ وَأَنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌ","en":"That1 is because Allāh causes the night to enter the day and causes the day to enter the night and because Allāh is Hearing and Seeing.","tr":"Thalika bi-anna Allaha yoolijuallayla fee annahari wayooliju annaharafee allayli waanna Allaha sameeAAun baseer","juz":17,"page":339},{"s":22,"a":62,"key":"22:62","ar":"ذَٰلِكَ بِأَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ وَأَنَّ مَا يَدْعُونَ مِن دُونِهِۦ هُوَ ٱلْبَـٰطِلُ وَأَنَّ ٱللَّهَ هُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ","en":"That is because Allāh is the True Reality, and that which they call upon other than Him is falsehood, and because Allāh is the Most High, the Grand.","tr":"Thalika bi-anna Allaha huwa alhaqquwaanna ma yadAAoona min doonihi huwa albatiluwaanna Allaha huwa alAAaliyyu alkabeer","juz":17,"page":339},{"s":22,"a":63,"key":"22:63","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً فَتُصْبِحُ ٱلْأَرْضُ مُخْضَرَّةً ۗ إِنَّ ٱللَّهَ لَطِيفٌ خَبِيرٌ","en":"Do you not see that Allāh has sent down rain from the sky and the earth becomes green? Indeed, Allāh is Subtle1 and Aware.2","tr":"Alam tara anna Allaha anzala mina assama-imaan fatusbihu al-ardu mukhdarrataninna Allaha lateefun khabeer","juz":17,"page":339},{"s":22,"a":64,"key":"22:64","ar":"لَّهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ وَإِنَّ ٱللَّهَ لَهُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ","en":"To Him belongs what is in the heavens and what is on the earth. And indeed, Allāh is the Free of need, the Praiseworthy.","tr":"Lahu ma fee assamawatiwama fee al-ardi wa-inna Allaha lahuwaalghaniyyu alhameed","juz":17,"page":339},{"s":22,"a":65,"key":"22:65","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ سَخَّرَ لَكُم مَّا فِى ٱلْأَرْضِ وَٱلْفُلْكَ تَجْرِى فِى ٱلْبَحْرِ بِأَمْرِهِۦ وَيُمْسِكُ ٱلسَّمَآءَ أَن تَقَعَ عَلَى ٱلْأَرْضِ إِلَّا بِإِذْنِهِۦٓ ۗ إِنَّ ٱللَّهَ بِٱلنَّاسِ لَرَءُوفٌ رَّحِيمٌ","en":"Do you not see that Allāh has subjected to you whatever is on the earth and the ships which run through the sea by His command? And He restrains the sky from falling upon the earth, unless by His permission. Indeed Allāh, to the people, is Kind and Merciful.","tr":"Alam tara anna Allaha sakhkhara lakumma fee al-ardi walfulka tajree fee albahribi-amrihi wayumsiku assamaa an taqaAAa AAalaal-ardi illa bi-ithnihi inna Allahabinnasi laraoofun raheem","juz":17,"page":340},{"s":22,"a":66,"key":"22:66","ar":"وَهُوَ ٱلَّذِىٓ أَحْيَاكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْ ۗ إِنَّ ٱلْإِنسَـٰنَ لَكَفُورٌ","en":"And He is the one who gave you life; then He causes you to die and then will [again] give you life. Indeed, mankind is ungrateful.","tr":"Wahuwa allathee ahyakumthumma yumeetukum thumma yuhyeekum inna al-insanalakafoor","juz":17,"page":340},{"s":22,"a":67,"key":"22:67","ar":"لِّكُلِّ أُمَّةٍ جَعَلْنَا مَنسَكًا هُمْ نَاسِكُوهُ ۖ فَلَا يُنَـٰزِعُنَّكَ فِى ٱلْأَمْرِ ۚ وَٱدْعُ إِلَىٰ رَبِّكَ ۖ إِنَّكَ لَعَلَىٰ هُدًى مُّسْتَقِيمٍ","en":"For every [religious] community We have appointed rites which they perform. So, [O Muḥammad], let them [i.e., the disbelievers] not contend with you over the matter but invite [them] to your Lord. Indeed, you are upon straight guidance.","tr":"Likulli ommatin jaAAalna mansakan humnasikoohu fala yunaziAAunnaka fee al-amri wadAAuila rabbika innaka laAAala hudan mustaqeem","juz":17,"page":340},{"s":22,"a":68,"key":"22:68","ar":"وَإِن جَـٰدَلُوكَ فَقُلِ ٱللَّهُ أَعْلَمُ بِمَا تَعْمَلُونَ","en":"And if they dispute with you, then say, \"Allāh is most knowing of what you do.","tr":"Wa-in jadalooka faquli AllahuaAAlamu bima taAAmaloon","juz":17,"page":340},{"s":22,"a":69,"key":"22:69","ar":"ٱللَّهُ يَحْكُمُ بَيْنَكُمْ يَوْمَ ٱلْقِيَـٰمَةِ فِيمَا كُنتُمْ فِيهِ تَخْتَلِفُونَ","en":"Allāh will judge between you on the Day of Resurrection concerning that over which you used to differ.\"","tr":"Allahu yahkumu baynakum yawmaalqiyamati feema kuntum feehi takhtalifoon","juz":17,"page":340},{"s":22,"a":70,"key":"22:70","ar":"أَلَمْ تَعْلَمْ أَنَّ ٱللَّهَ يَعْلَمُ مَا فِى ٱلسَّمَآءِ وَٱلْأَرْضِ ۗ إِنَّ ذَٰلِكَ فِى كِتَـٰبٍ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌ","en":"Do you not know that Allāh knows what is in the heaven and earth? Indeed, that is in a Record.1 Indeed that, for Allāh, is easy.","tr":"Alam taAAlam anna Allaha yaAAlamu mafee assama-i wal-ardi inna thalikafee kitabin inna thalika AAala Allahiyaseer","juz":17,"page":340},{"s":22,"a":71,"key":"22:71","ar":"وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَمْ يُنَزِّلْ بِهِۦ سُلْطَـٰنًا وَمَا لَيْسَ لَهُم بِهِۦ عِلْمٌ ۗ وَمَا لِلظَّـٰلِمِينَ مِن نَّصِيرٍ","en":"And they worship besides Allāh that for which He has not sent down authority and that of which they have no knowledge. And there will not be for the wrongdoers any helper.","tr":"WayaAAbudoona min dooni Allahi malam yunazzil bihi sultanan wama laysa lahum bihiAAilmun wama liththalimeenamin naseer","juz":17,"page":340},{"s":22,"a":72,"key":"22:72","ar":"وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَـٰتُنَا بَيِّنَـٰتٍ تَعْرِفُ فِى وُجُوهِ ٱلَّذِينَ كَفَرُوا۟ ٱلْمُنكَرَ ۖ يَكَادُونَ يَسْطُونَ بِٱلَّذِينَ يَتْلُونَ عَلَيْهِمْ ءَايَـٰتِنَا ۗ قُلْ أَفَأُنَبِّئُكُم بِشَرٍّ مِّن ذَٰلِكُمُ ۗ ٱلنَّارُ وَعَدَهَا ٱللَّهُ ٱلَّذِينَ كَفَرُوا۟ ۖ وَبِئْسَ ٱلْمَصِيرُ","en":"And when Our verses are recited to them as clear evidences, you recognize in the faces of those who disbelieve disapproval. They are almost on the verge of assaulting those who recite to them Our verses. Say, \"Then shall I inform you of [what is] worse than that?1 [It is] the Fire which Allāh has promised those who disbelieve, and wretched is the destination.\"","tr":"Wa-itha tutla AAalayhim ayatunabayyinatin taAArifu fee wujoohi allatheena kafarooalmunkara yakadoona yastoona billatheenayatloona AAalayhim ayatina qulafaonabbi-okum bisharrin min thalikum annaruwaAAadaha Allahu allatheena kafaroo wabi/saalmaseer","juz":17,"page":340},{"s":22,"a":73,"key":"22:73","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ ضُرِبَ مَثَلٌ فَٱسْتَمِعُوا۟ لَهُۥٓ ۚ إِنَّ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ لَن يَخْلُقُوا۟ ذُبَابًا وَلَوِ ٱجْتَمَعُوا۟ لَهُۥ ۖ وَإِن يَسْلُبْهُمُ ٱلذُّبَابُ شَيْـًٔا لَّا يَسْتَنقِذُوهُ مِنْهُ ۚ ضَعُفَ ٱلطَّالِبُ وَٱلْمَطْلُوبُ","en":"O people, an example is presented, so listen to it. Indeed, those you invoke besides Allāh will never create [as much as] a fly, even if they gathered together for it [i.e., that purpose]. And if the fly should steal from them a [tiny] thing, they could not recover it from him. Weak are the pursuer and pursued.1","tr":"Ya ayyuha annasuduriba mathalun fastamiAAoo lahu inna allatheenatadAAoona min dooni Allahi lan yakhluqoo thubabanwalawi ijtamaAAoo lahu wa-in yaslubuhumu aththubabushay-an la yastanqithoohu minhu daAAufa attalibuwalmatloob","juz":17,"page":341},{"s":22,"a":74,"key":"22:74","ar":"مَا قَدَرُوا۟ ٱللَّهَ حَقَّ قَدْرِهِۦٓ ۗ إِنَّ ٱللَّهَ لَقَوِىٌّ عَزِيزٌ","en":"They have not appraised Allāh with true appraisal.1 Indeed, Allāh is Powerful and Exalted in Might.","tr":"Ma qadaroo Allaha haqqaqadrihi inna Allaha laqawiyyun AAazeez","juz":17,"page":341},{"s":22,"a":75,"key":"22:75","ar":"ٱللَّهُ يَصْطَفِى مِنَ ٱلْمَلَـٰٓئِكَةِ رُسُلًا وَمِنَ ٱلنَّاسِ ۚ إِنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌ","en":"Allāh chooses from the angels messengers and from the people. Indeed, Allāh is Hearing and Seeing.","tr":"Allahu yastafee mina almala-ikatirusulan wamina annasi inna Allaha sameeAAunbaseer","juz":17,"page":341},{"s":22,"a":76,"key":"22:76","ar":"يَعْلَمُ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ ۗ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ","en":"He knows what is [presently] before them and what will be after them.1 And to Allāh will be returned [all] matters.","tr":"YaAAlamu ma bayna aydeehim wamakhalfahum wa-ila Allahi turjaAAu al-omoor","juz":17,"page":341},{"s":22,"a":77,"key":"22:77","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱرْكَعُوا۟ وَٱسْجُدُوا۟ وَٱعْبُدُوا۟ رَبَّكُمْ وَٱفْعَلُوا۟ ٱلْخَيْرَ لَعَلَّكُمْ تُفْلِحُونَ ۩","en":"O you who have believed, bow and prostrate and worship your Lord and do good - that you may succeed.","tr":"Ya ayyuha allatheena amanooirkaAAoo wasjudoo waAAbudoo rabbakum wafAAalooalkhayra laAAallakum tuflihoon","juz":17,"page":341},{"s":22,"a":78,"key":"22:78","ar":"وَجَـٰهِدُوا۟ فِى ٱللَّهِ حَقَّ جِهَادِهِۦ ۚ هُوَ ٱجْتَبَىٰكُمْ وَمَا جَعَلَ عَلَيْكُمْ فِى ٱلدِّينِ مِنْ حَرَجٍ ۚ مِّلَّةَ أَبِيكُمْ إِبْرَٰهِيمَ ۚ هُوَ سَمَّىٰكُمُ ٱلْمُسْلِمِينَ مِن قَبْلُ وَفِى هَـٰذَا لِيَكُونَ ٱلرَّسُولُ شَهِيدًا عَلَيْكُمْ وَتَكُونُوا۟ شُهَدَآءَ عَلَى ٱلنَّاسِ ۚ فَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَٱعْتَصِمُوا۟ بِٱللَّهِ هُوَ مَوْلَىٰكُمْ ۖ فَنِعْمَ ٱلْمَوْلَىٰ وَنِعْمَ ٱلنَّصِيرُ","en":"And strive for Allāh with the striving due to Him. He has chosen you and has not placed upon you in the religion any difficulty. [It is] the religion of your father, Abraham. He [i.e., Allāh] named you \"Muslims\" before [in former scriptures] and in this [revelation] that the Messenger may be a witness over you and you may be witnesses over the people. So establish prayer and give zakāh and hold fast to Allāh. He is your protector; and excellent is the protector, and excellent is the helper.","tr":"Wajahidoo fee Allahi haqqajihadihi huwa ijtabakum wama jaAAalaAAalaykum fee addeeni min harajin millata abeekumibraheema huwa sammakumu almuslimeena min qabluwafee hatha liyakoona arrasoolu shaheedanAAalaykum watakoonoo shuhadaa AAala annasifaaqeemoo assalata waatoo azzakatawaAAtasimoo billahi huwa mawlakumfaniAAma almawla waniAAma annaseer","juz":17,"page":341},{"s":23,"a":1,"key":"23:1","ar":" قَدْ أَفْلَحَ ٱلْمُؤْمِنُونَ","en":"Certainly will the believers have succeeded:","tr":"Qad aflaha almu/minoon","juz":18,"page":342},{"s":23,"a":2,"key":"23:2","ar":"ٱلَّذِينَ هُمْ فِى صَلَاتِهِمْ خَـٰشِعُونَ","en":"They who are during their prayer humbly intent","tr":"Allatheena hum fee salatihimkhashiAAoon","juz":18,"page":342},{"s":23,"a":3,"key":"23:3","ar":"وَٱلَّذِينَ هُمْ عَنِ ٱللَّغْوِ مُعْرِضُونَ","en":"And they who turn away from ill speech","tr":"Wallatheena hum AAani allaghwimuAAridoon","juz":18,"page":342},{"s":23,"a":4,"key":"23:4","ar":"وَٱلَّذِينَ هُمْ لِلزَّكَوٰةِ فَـٰعِلُونَ","en":"And they who are observant of zakāh","tr":"Wallatheena hum lizzakatifaAAiloon","juz":18,"page":342},{"s":23,"a":5,"key":"23:5","ar":"وَٱلَّذِينَ هُمْ لِفُرُوجِهِمْ حَـٰفِظُونَ","en":"And they who guard their private parts","tr":"Wallatheena hum lifuroojihim hafithoon","juz":18,"page":342},{"s":23,"a":6,"key":"23:6","ar":"إِلَّا عَلَىٰٓ أَزْوَٰجِهِمْ أَوْ مَا مَلَكَتْ أَيْمَـٰنُهُمْ فَإِنَّهُمْ غَيْرُ مَلُومِينَ","en":"Except from their wives or those their right hands possess,1 for indeed, they will not be blamed -","tr":"Illa AAala azwajihim awma malakat aymanuhum fa-innahum ghayru maloomeen","juz":18,"page":342},{"s":23,"a":7,"key":"23:7","ar":"فَمَنِ ٱبْتَغَىٰ وَرَآءَ ذَٰلِكَ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْعَادُونَ","en":"But whoever seeks beyond that, then those are the transgressors -","tr":"Famani ibtagha waraa thalikafaola-ika humu alAAadoon","juz":18,"page":342},{"s":23,"a":8,"key":"23:8","ar":"وَٱلَّذِينَ هُمْ لِأَمَـٰنَـٰتِهِمْ وَعَهْدِهِمْ رَٰعُونَ","en":"And they who are to their trusts and their promises attentive","tr":"Wallatheena hum li-amanatihimwaAAahdihim raAAoon","juz":18,"page":342},{"s":23,"a":9,"key":"23:9","ar":"وَٱلَّذِينَ هُمْ عَلَىٰ صَلَوَٰتِهِمْ يُحَافِظُونَ","en":"And they who carefully maintain their prayers -","tr":"Wallatheena hum AAala salawatihimyuhafithoon","juz":18,"page":342},{"s":23,"a":10,"key":"23:10","ar":"أُو۟لَـٰٓئِكَ هُمُ ٱلْوَٰرِثُونَ","en":"Those are the inheritors","tr":"Ola-ika humu alwarithoon","juz":18,"page":342},{"s":23,"a":11,"key":"23:11","ar":"ٱلَّذِينَ يَرِثُونَ ٱلْفِرْدَوْسَ هُمْ فِيهَا خَـٰلِدُونَ","en":"Who will inherit al-Firdaus.1 They will abide therein eternally.","tr":"Allatheena yarithoona alfirdawsa humfeeha khalidoon","juz":18,"page":342},{"s":23,"a":12,"key":"23:12","ar":"وَلَقَدْ خَلَقْنَا ٱلْإِنسَـٰنَ مِن سُلَـٰلَةٍ مِّن طِينٍ","en":"And certainly did We create man from an extract of clay.","tr":"Walaqad khalaqna al-insana minsulalatin min teen","juz":18,"page":342},{"s":23,"a":13,"key":"23:13","ar":"ثُمَّ جَعَلْنَـٰهُ نُطْفَةً فِى قَرَارٍ مَّكِينٍ","en":"Then We placed him as a sperm-drop1 in a firm lodging [i.e., the womb].","tr":"Thumma jaAAalnahu nutfatan feeqararin makeen","juz":18,"page":342},{"s":23,"a":14,"key":"23:14","ar":"ثُمَّ خَلَقْنَا ٱلنُّطْفَةَ عَلَقَةً فَخَلَقْنَا ٱلْعَلَقَةَ مُضْغَةً فَخَلَقْنَا ٱلْمُضْغَةَ عِظَـٰمًا فَكَسَوْنَا ٱلْعِظَـٰمَ لَحْمًا ثُمَّ أَنشَأْنَـٰهُ خَلْقًا ءَاخَرَ ۚ فَتَبَارَكَ ٱللَّهُ أَحْسَنُ ٱلْخَـٰلِقِينَ","en":"Then We made the sperm-drop into a clinging clot, and We made the clot into a lump [of flesh], and We made [from] the lump, bones, and We covered the bones with flesh; then We developed him into another creation. So blessed is Allāh, the best of creators.1","tr":"Thumma khalaqna annutfataAAalaqatan fakhalaqna alAAalaqata mudghatanfakhalaqna almudghata AAithamanfakasawna alAAithama lahmanthumma ansha/nahu khalqan akhara fatabarakaAllahu ahsanu alkhaliqeen","juz":18,"page":342},{"s":23,"a":15,"key":"23:15","ar":"ثُمَّ إِنَّكُم بَعْدَ ذَٰلِكَ لَمَيِّتُونَ","en":"Then indeed, after that you are to die.","tr":"Thumma innakum baAAda thalikalamayyitoon","juz":18,"page":342},{"s":23,"a":16,"key":"23:16","ar":"ثُمَّ إِنَّكُمْ يَوْمَ ٱلْقِيَـٰمَةِ تُبْعَثُونَ","en":"Then indeed you, on the Day of Resurrection, will be resurrected.","tr":"Thumma innakum yawma alqiyamatitubAAathoon","juz":18,"page":342},{"s":23,"a":17,"key":"23:17","ar":"وَلَقَدْ خَلَقْنَا فَوْقَكُمْ سَبْعَ طَرَآئِقَ وَمَا كُنَّا عَنِ ٱلْخَلْقِ غَـٰفِلِينَ","en":"And We have created above you seven layered heavens, and never have We been of [Our] creation unaware.","tr":"Walaqad khalaqna fawqakum sabAAa tara-iqawama kunna AAani alkhalqi ghafileen","juz":18,"page":342},{"s":23,"a":18,"key":"23:18","ar":"وَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءًۢ بِقَدَرٍ فَأَسْكَنَّـٰهُ فِى ٱلْأَرْضِ ۖ وَإِنَّا عَلَىٰ ذَهَابٍۭ بِهِۦ لَقَـٰدِرُونَ","en":"And We have sent down rain from the sky in a measured amount and settled it in the earth. And indeed, We are Able to take it away.","tr":"Waanzalna mina assama-imaan biqadarin faaskannahu fee al-ardiwa-inna AAala thahabin bihi laqadiroon","juz":18,"page":343},{"s":23,"a":19,"key":"23:19","ar":"فَأَنشَأْنَا لَكُم بِهِۦ جَنَّـٰتٍ مِّن نَّخِيلٍ وَأَعْنَـٰبٍ لَّكُمْ فِيهَا فَوَٰكِهُ كَثِيرَةٌ وَمِنْهَا تَأْكُلُونَ","en":"And We brought forth for you thereby gardens of palm trees and grapevines in which for you are abundant fruits and from which you eat.","tr":"Faansha/na lakum bihi jannatinmin nakheelin waaAAnabin lakum feeha fawakihukatheeratun waminha ta/kuloon","juz":18,"page":343},{"s":23,"a":20,"key":"23:20","ar":"وَشَجَرَةً تَخْرُجُ مِن طُورِ سَيْنَآءَ تَنۢبُتُ بِٱلدُّهْنِ وَصِبْغٍ لِّلْـَٔاكِلِينَ","en":"And [We brought forth] a tree issuing from Mount Sinai which produces oil and food [i.e., olives] for those who eat.","tr":"Washajaratan takhruju min toori saynaatanbutu bidduhni wasibghin lilakileen","juz":18,"page":343},{"s":23,"a":21,"key":"23:21","ar":"وَإِنَّ لَكُمْ فِى ٱلْأَنْعَـٰمِ لَعِبْرَةً ۖ نُّسْقِيكُم مِّمَّا فِى بُطُونِهَا وَلَكُمْ فِيهَا مَنَـٰفِعُ كَثِيرَةٌ وَمِنْهَا تَأْكُلُونَ","en":"And indeed, for you in livestock is a lesson. We give you drink from that which is in their bellies, and for you in them are numerous benefits, and from them you eat.","tr":"Wa-inna lakum fee al-anAAamilaAAibratan nusqeekum mimma fee butoonihawalakum feeha manafiAAu katheeratun waminhata/kuloon","juz":18,"page":343},{"s":23,"a":22,"key":"23:22","ar":"وَعَلَيْهَا وَعَلَى ٱلْفُلْكِ تُحْمَلُونَ","en":"And upon them and on ships you are carried.","tr":"WaAAalayha waAAala alfulki tuhmaloon","juz":18,"page":343},{"s":23,"a":23,"key":"23:23","ar":"وَلَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَقَالَ يَـٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَـٰهٍ غَيْرُهُۥٓ ۖ أَفَلَا تَتَّقُونَ","en":"And We had certainly sent Noah to his people, and he said, \"O my people, worship Allāh; you have no deity other than Him; then will you not fear Him?\"","tr":"Walaqad arsalna noohan ilaqawmihi faqala ya qawmi oAAbudoo Allaha malakum min ilahin ghayruhu afala tattaqoon","juz":18,"page":343},{"s":23,"a":24,"key":"23:24","ar":"فَقَالَ ٱلْمَلَؤُا۟ ٱلَّذِينَ كَفَرُوا۟ مِن قَوْمِهِۦ مَا هَـٰذَآ إِلَّا بَشَرٌ مِّثْلُكُمْ يُرِيدُ أَن يَتَفَضَّلَ عَلَيْكُمْ وَلَوْ شَآءَ ٱللَّهُ لَأَنزَلَ مَلَـٰٓئِكَةً مَّا سَمِعْنَا بِهَـٰذَا فِىٓ ءَابَآئِنَا ٱلْأَوَّلِينَ","en":"But the eminent among those who disbelieved from his people said, \"This is not but a man like yourselves who wishes to take precedence over you; and if Allāh had willed [to send a messenger], He would have sent down angels. We have not heard of this among our forefathers.","tr":"Faqala almalao allatheenakafaroo min qawmihi ma hatha illa basharunmithlukum yureedu an yatafaddala AAalaykum walaw shaaAllahu laanzala mala-ikatan ma samiAAnabihatha fee aba-ina al-awwaleen","juz":18,"page":343},{"s":23,"a":25,"key":"23:25","ar":"إِنْ هُوَ إِلَّا رَجُلٌۢ بِهِۦ جِنَّةٌ فَتَرَبَّصُوا۟ بِهِۦ حَتَّىٰ حِينٍ","en":"He is not but a man possessed with madness, so wait concerning him for a time.\"","tr":"In huwa illa rajulun bihi jinnatunfatarabbasoo bihi hatta heen","juz":18,"page":343},{"s":23,"a":26,"key":"23:26","ar":"قَالَ رَبِّ ٱنصُرْنِى بِمَا كَذَّبُونِ","en":"[Noah] said, \"My Lord, support me because they have denied me.\"","tr":"Qala rabbi onsurnee bimakaththaboon","juz":18,"page":343},{"s":23,"a":27,"key":"23:27","ar":"فَأَوْحَيْنَآ إِلَيْهِ أَنِ ٱصْنَعِ ٱلْفُلْكَ بِأَعْيُنِنَا وَوَحْيِنَا فَإِذَا جَآءَ أَمْرُنَا وَفَارَ ٱلتَّنُّورُ ۙ فَٱسْلُكْ فِيهَا مِن كُلٍّ زَوْجَيْنِ ٱثْنَيْنِ وَأَهْلَكَ إِلَّا مَن سَبَقَ عَلَيْهِ ٱلْقَوْلُ مِنْهُمْ ۖ وَلَا تُخَـٰطِبْنِى فِى ٱلَّذِينَ ظَلَمُوٓا۟ ۖ إِنَّهُم مُّغْرَقُونَ","en":"So We inspired to him, \"Construct the ship under Our observation and Our inspiration, and when Our command comes and the oven overflows,1 put into it [i.e., the ship] from each [creature] two mates and your family, except him for whom the decree [of destruction] has proceeded. And do not address Me concerning those who have wronged; indeed, they are to be drowned.","tr":"Faawhayna ilayhi ani isnaAAialfulka bi-aAAyunina wawahyina fa-ithajaa amruna wafara attannooru faslukfeeha min kullin zawjayni ithnayni waahlaka illaman sabaqa AAalayhi alqawlu minhum wala tukhatibneefee allatheena thalamoo innahum mughraqoon","juz":18,"page":343},{"s":23,"a":28,"key":"23:28","ar":"فَإِذَا ٱسْتَوَيْتَ أَنتَ وَمَن مَّعَكَ عَلَى ٱلْفُلْكِ فَقُلِ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى نَجَّىٰنَا مِنَ ٱلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"And when you have boarded the ship, you and those with you, then say, 'Praise to Allāh who has saved us from the wrongdoing people.'","tr":"Fa-itha istawayta anta waman maAAakaAAala alfulki faquli alhamdu lillahi allatheenajjana mina alqawmi aththalimeen","juz":18,"page":344},{"s":23,"a":29,"key":"23:29","ar":"وَقُل رَّبِّ أَنزِلْنِى مُنزَلًا مُّبَارَكًا وَأَنتَ خَيْرُ ٱلْمُنزِلِينَ","en":"And say, 'My Lord, let me land at a blessed landing place, and You are the best to accommodate [us].'\"","tr":"Waqul rabbi anzilnee munzalan mubarakanwaanta khayru almunzileen","juz":18,"page":344},{"s":23,"a":30,"key":"23:30","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ وَإِن كُنَّا لَمُبْتَلِينَ","en":"Indeed in that are signs, and indeed, We are ever testing [Our servants].","tr":"Inna fee thalika laayatinwa-in kunna lamubtaleen","juz":18,"page":344},{"s":23,"a":31,"key":"23:31","ar":"ثُمَّ أَنشَأْنَا مِنۢ بَعْدِهِمْ قَرْنًا ءَاخَرِينَ","en":"Then We produced after them a generation of others.","tr":"Thumma ansha/na min baAAdihim qarnan akhareen","juz":18,"page":344},{"s":23,"a":32,"key":"23:32","ar":"فَأَرْسَلْنَا فِيهِمْ رَسُولًا مِّنْهُمْ أَنِ ٱعْبُدُوا۟ ٱللَّهَ مَا لَكُم مِّنْ إِلَـٰهٍ غَيْرُهُۥٓ ۖ أَفَلَا تَتَّقُونَ","en":"And We sent among them a messenger1 from themselves, [saying], \"Worship Allāh; you have no deity other than Him; then will you not fear Him?\"","tr":"Faarsalna feehim rasoolan minhum anioAAbudoo Allaha ma lakum min ilahin ghayruhuafala tattaqoon","juz":18,"page":344},{"s":23,"a":33,"key":"23:33","ar":"وَقَالَ ٱلْمَلَأُ مِن قَوْمِهِ ٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِلِقَآءِ ٱلْـَٔاخِرَةِ وَأَتْرَفْنَـٰهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا مَا هَـٰذَآ إِلَّا بَشَرٌ مِّثْلُكُمْ يَأْكُلُ مِمَّا تَأْكُلُونَ مِنْهُ وَيَشْرَبُ مِمَّا تَشْرَبُونَ","en":"And the eminent among his people who disbelieved and denied the meeting of the Hereafter while We had given them luxury in the worldly life said, \"This is not but a man like yourselves. He eats of that from which you eat and drinks of what you drink.","tr":"Waqala almalao min qawmihi allatheenakafaroo wakaththaboo biliqa-i al-akhiratiwaatrafnahum fee alhayati addunyama hatha illa basharun mithlukum ya/kulumimma ta/kuloona minhu wayashrabu mimma tashraboon","juz":18,"page":344},{"s":23,"a":34,"key":"23:34","ar":"وَلَئِنْ أَطَعْتُم بَشَرًا مِّثْلَكُمْ إِنَّكُمْ إِذًا لَّخَـٰسِرُونَ","en":"And if you should obey a man like yourselves, indeed, you would then be losers.","tr":"Wala-in ataAAtum basharan mithlakuminnakum ithan lakhasiroon","juz":18,"page":344},{"s":23,"a":35,"key":"23:35","ar":"أَيَعِدُكُمْ أَنَّكُمْ إِذَا مِتُّمْ وَكُنتُمْ تُرَابًا وَعِظَـٰمًا أَنَّكُم مُّخْرَجُونَ","en":"Does he promise you that when you have died and become dust and bones that you will be brought forth [once more]?","tr":"AyaAAidukum annakum itha mittumwakuntum turaban waAAithaman annakummukhrajoon","juz":18,"page":344},{"s":23,"a":36,"key":"23:36","ar":"۞ هَيْهَاتَ هَيْهَاتَ لِمَا تُوعَدُونَ","en":"How far, how far, is that which you are promised.1","tr":"Hayhata hayhata limatooAAadoon","juz":18,"page":344},{"s":23,"a":37,"key":"23:37","ar":"إِنْ هِىَ إِلَّا حَيَاتُنَا ٱلدُّنْيَا نَمُوتُ وَنَحْيَا وَمَا نَحْنُ بِمَبْعُوثِينَ","en":"It [i.e., life] is not but our worldly life - we die and live, but we will not be resurrected.","tr":"In hiya illa hayatunaaddunya namootu wanahya wamanahnu bimabAAootheen","juz":18,"page":344},{"s":23,"a":38,"key":"23:38","ar":"إِنْ هُوَ إِلَّا رَجُلٌ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا وَمَا نَحْنُ لَهُۥ بِمُؤْمِنِينَ","en":"He is not but a man who has invented a lie about Allāh, and we will not believe him.\"","tr":"In huwa illa rajulun iftaraAAala Allahi kathiban wama nahnulahu bimu/mineen","juz":18,"page":344},{"s":23,"a":39,"key":"23:39","ar":"قَالَ رَبِّ ٱنصُرْنِى بِمَا كَذَّبُونِ","en":"He said, \"My Lord, support me because they have denied me.\"","tr":"Qala rabbi onsurnee bimakaththaboon","juz":18,"page":344},{"s":23,"a":40,"key":"23:40","ar":"قَالَ عَمَّا قَلِيلٍ لَّيُصْبِحُنَّ نَـٰدِمِينَ","en":"[Allāh] said, \"After a little, they will surely become regretful.\"","tr":"Qala AAamma qaleelin layusbihunnanadimeen","juz":18,"page":344},{"s":23,"a":41,"key":"23:41","ar":"فَأَخَذَتْهُمُ ٱلصَّيْحَةُ بِٱلْحَقِّ فَجَعَلْنَـٰهُمْ غُثَآءً ۚ فَبُعْدًا لِّلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"So the shriek1 seized them in truth,2 and We made them as [plant] stubble. Then away with the wrongdoing people.","tr":"Faakhathat-humu assayhatubilhaqqi fajaAAalnahum ghuthaanfabuAAdan lilqawmi aththalimeen","juz":18,"page":344},{"s":23,"a":42,"key":"23:42","ar":"ثُمَّ أَنشَأْنَا مِنۢ بَعْدِهِمْ قُرُونًا ءَاخَرِينَ","en":"Then We produced after them other generations.","tr":"Thumma ansha/na min baAAdihimquroonan akhareen","juz":18,"page":344},{"s":23,"a":43,"key":"23:43","ar":"مَا تَسْبِقُ مِنْ أُمَّةٍ أَجَلَهَا وَمَا يَسْتَـْٔخِرُونَ","en":"No nation will precede its time [of termination], nor will they remain [thereafter].","tr":"Ma tasbiqu min ommatin ajalahawama yasta/khiroon","juz":18,"page":345},{"s":23,"a":44,"key":"23:44","ar":"ثُمَّ أَرْسَلْنَا رُسُلَنَا تَتْرَا ۖ كُلَّ مَا جَآءَ أُمَّةً رَّسُولُهَا كَذَّبُوهُ ۚ فَأَتْبَعْنَا بَعْضَهُم بَعْضًا وَجَعَلْنَـٰهُمْ أَحَادِيثَ ۚ فَبُعْدًا لِّقَوْمٍ لَّا يُؤْمِنُونَ","en":"Then We sent Our messengers in succession. Every time there came to a nation its messenger, they denied him, so We made them follow one another [to destruction], and We made them narrations.1 So away with a people who do not believe.","tr":"Thumma arsalna rusulana tatrakulla ma jaa ommatan rasooluha kaththaboohufaatbaAAna baAAdahum baAAdan wajaAAalnahumahadeetha fabuAAdan liqawmin la yu/minoon","juz":18,"page":345},{"s":23,"a":45,"key":"23:45","ar":"ثُمَّ أَرْسَلْنَا مُوسَىٰ وَأَخَاهُ هَـٰرُونَ بِـَٔايَـٰتِنَا وَسُلْطَـٰنٍ مُّبِينٍ","en":"Then We sent Moses and his brother Aaron with Our signs and a clear authority1","tr":"Thumma arsalna moosa waakhahuharoona bi-ayatina wasultaninmubeen","juz":18,"page":345},{"s":23,"a":46,"key":"23:46","ar":"إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَٱسْتَكْبَرُوا۟ وَكَانُوا۟ قَوْمًا عَالِينَ","en":"To Pharaoh and his establishment, but they were arrogant and were a haughty people.","tr":"Ila firAAawna wamala-ihi fastakbaroowakanoo qawman AAaleen","juz":18,"page":345},{"s":23,"a":47,"key":"23:47","ar":"فَقَالُوٓا۟ أَنُؤْمِنُ لِبَشَرَيْنِ مِثْلِنَا وَقَوْمُهُمَا لَنَا عَـٰبِدُونَ","en":"They said, \"Should we believe two men like ourselves while their people are for us in servitude?\"","tr":"Faqaloo anu/minu libasharayni mithlinawaqawmuhuma lana AAabidoon","juz":18,"page":345},{"s":23,"a":48,"key":"23:48","ar":"فَكَذَّبُوهُمَا فَكَانُوا۟ مِنَ ٱلْمُهْلَكِينَ","en":"So they denied them and were of those destroyed.","tr":"Fakaththaboohuma fakanoomina almuhlakeen","juz":18,"page":345},{"s":23,"a":49,"key":"23:49","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ لَعَلَّهُمْ يَهْتَدُونَ","en":"And We certainly gave Moses the Scripture that perhaps they1 would be guided.","tr":"Walaqad atayna moosaalkitaba laAAallahum yahtadoon","juz":18,"page":345},{"s":23,"a":50,"key":"23:50","ar":"وَجَعَلْنَا ٱبْنَ مَرْيَمَ وَأُمَّهُۥٓ ءَايَةً وَءَاوَيْنَـٰهُمَآ إِلَىٰ رَبْوَةٍ ذَاتِ قَرَارٍ وَمَعِينٍ","en":"And We made the son of Mary and his mother a sign and sheltered them within a high ground having level [areas] and flowing water.","tr":"WajaAAalna ibna maryama waommahu ayatanwaawaynahuma ila rabwatin thatiqararin wamaAAeen","juz":18,"page":345},{"s":23,"a":51,"key":"23:51","ar":"يَـٰٓأَيُّهَا ٱلرُّسُلُ كُلُوا۟ مِنَ ٱلطَّيِّبَـٰتِ وَٱعْمَلُوا۟ صَـٰلِحًا ۖ إِنِّى بِمَا تَعْمَلُونَ عَلِيمٌ","en":"[Allāh said], \"O messengers, eat from the good foods and work righteousness. Indeed I, of what you do, am Knowing.","tr":"Ya ayyuha arrusulukuloo mina attayyibati waAAmaloo salihaninnee bima taAAmaloona AAaleem","juz":18,"page":345},{"s":23,"a":52,"key":"23:52","ar":"وَإِنَّ هَـٰذِهِۦٓ أُمَّتُكُمْ أُمَّةً وَٰحِدَةً وَأَنَا۠ رَبُّكُمْ فَٱتَّقُونِ","en":"And indeed this, your religion, is one religion,1 and I am your Lord, so fear Me.\"","tr":"Wa-inna hathihi ommatukum ommatan wahidatanwaana rabbukum fattaqoon","juz":18,"page":345},{"s":23,"a":53,"key":"23:53","ar":"فَتَقَطَّعُوٓا۟ أَمْرَهُم بَيْنَهُمْ زُبُرًا ۖ كُلُّ حِزْبٍۭ بِمَا لَدَيْهِمْ فَرِحُونَ","en":"But they [i.e., the people] divided their religion among them into portions [i.e., sects] - each faction, in what it has,1 rejoicing.","tr":"FataqattaAAoo amrahum baynahumzuburan kullu hizbin bima ladayhim farihoon","juz":18,"page":345},{"s":23,"a":54,"key":"23:54","ar":"فَذَرْهُمْ فِى غَمْرَتِهِمْ حَتَّىٰ حِينٍ","en":"So leave them in their confusion for a time.","tr":"Fatharhum fee ghamratihim hattaheen","juz":18,"page":345},{"s":23,"a":55,"key":"23:55","ar":"أَيَحْسَبُونَ أَنَّمَا نُمِدُّهُم بِهِۦ مِن مَّالٍ وَبَنِينَ","en":"Do they think that what We extend to them of wealth and children","tr":"Ayahsaboona annama numidduhumbihi min malin wabaneen","juz":18,"page":345},{"s":23,"a":56,"key":"23:56","ar":"نُسَارِعُ لَهُمْ فِى ٱلْخَيْرَٰتِ ۚ بَل لَّا يَشْعُرُونَ","en":"Is [because] We hasten for them good things? Rather, they do not perceive.1","tr":"NusariAAu lahum fee alkhayratibal la yashAAuroon","juz":18,"page":345},{"s":23,"a":57,"key":"23:57","ar":"إِنَّ ٱلَّذِينَ هُم مِّنْ خَشْيَةِ رَبِّهِم مُّشْفِقُونَ","en":"Indeed, they who are apprehensive from fear of their Lord","tr":"Inna allatheena hum min khashyatirabbihim mushfiqoon","juz":18,"page":345},{"s":23,"a":58,"key":"23:58","ar":"وَٱلَّذِينَ هُم بِـَٔايَـٰتِ رَبِّهِمْ يُؤْمِنُونَ","en":"And they who believe in the signs of their Lord","tr":"Wallatheena hum bi-ayatirabbihim yu/minoon","juz":18,"page":345},{"s":23,"a":59,"key":"23:59","ar":"وَٱلَّذِينَ هُم بِرَبِّهِمْ لَا يُشْرِكُونَ","en":"And they who do not associate anything with their Lord","tr":"Wallatheena hum birabbihim layushrikoon","juz":18,"page":345},{"s":23,"a":60,"key":"23:60","ar":"وَٱلَّذِينَ يُؤْتُونَ مَآ ءَاتَوا۟ وَّقُلُوبُهُمْ وَجِلَةٌ أَنَّهُمْ إِلَىٰ رَبِّهِمْ رَٰجِعُونَ","en":"And they who give what they give while their hearts are fearful1 because they will be returning to their Lord -","tr":"Wallatheena yu/toona maataw waquloobuhum wajilatun annahum ila rabbihim rajiAAoon","juz":18,"page":346},{"s":23,"a":61,"key":"23:61","ar":"أُو۟لَـٰٓئِكَ يُسَـٰرِعُونَ فِى ٱلْخَيْرَٰتِ وَهُمْ لَهَا سَـٰبِقُونَ","en":"It is those who hasten to good deeds, and they outstrip [others] therein.","tr":"Ola-ika yusariAAoona feealkhayrati wahum laha sabiqoon","juz":18,"page":346},{"s":23,"a":62,"key":"23:62","ar":"وَلَا نُكَلِّفُ نَفْسًا إِلَّا وُسْعَهَا ۖ وَلَدَيْنَا كِتَـٰبٌ يَنطِقُ بِٱلْحَقِّ ۚ وَهُمْ لَا يُظْلَمُونَ","en":"And We charge no soul except [with that within] its capacity, and with Us is a record which speaks with truth; and they will not be wronged.","tr":"Wala nukallifu nafsan illawusAAaha waladayna kitabun yantiqu bilhaqqiwahum la yuthlamoon","juz":18,"page":346},{"s":23,"a":63,"key":"23:63","ar":"بَلْ قُلُوبُهُمْ فِى غَمْرَةٍ مِّنْ هَـٰذَا وَلَهُمْ أَعْمَـٰلٌ مِّن دُونِ ذَٰلِكَ هُمْ لَهَا عَـٰمِلُونَ","en":"But their hearts are covered with confusion over this, and they have [evil] deeds besides that [i.e., disbelief] which they are doing,","tr":"Bal quloobuhum fee ghamratin min hathawalahum aAAmalun min dooni thalika hum lahaAAamiloon","juz":18,"page":346},{"s":23,"a":64,"key":"23:64","ar":"حَتَّىٰٓ إِذَآ أَخَذْنَا مُتْرَفِيهِم بِٱلْعَذَابِ إِذَا هُمْ يَجْـَٔرُونَ","en":"Until when We seize their affluent ones with punishment,1 at once they are crying [to Allāh] for help.","tr":"Hatta itha akhathnamutrafeehim bilAAathabi itha hum yaj-aroon","juz":18,"page":346},{"s":23,"a":65,"key":"23:65","ar":"لَا تَجْـَٔرُوا۟ ٱلْيَوْمَ ۖ إِنَّكُم مِّنَّا لَا تُنصَرُونَ","en":"Do not cry out today. Indeed, by Us you will not be helped.","tr":"La taj-aroo alyawma innakum minnala tunsaroon","juz":18,"page":346},{"s":23,"a":66,"key":"23:66","ar":"قَدْ كَانَتْ ءَايَـٰتِى تُتْلَىٰ عَلَيْكُمْ فَكُنتُمْ عَلَىٰٓ أَعْقَـٰبِكُمْ تَنكِصُونَ","en":"My verses had already been recited to you, but you were turning back on your heels.","tr":"Qad kanat ayatee tutlaAAalaykum fakuntum AAala aAAqabikum tankisoon","juz":18,"page":346},{"s":23,"a":67,"key":"23:67","ar":"مُسْتَكْبِرِينَ بِهِۦ سَـٰمِرًا تَهْجُرُونَ","en":"In arrogance regarding it,1 conversing by night, speaking evil.","tr":"Mustakbireena bihi samiran tahjuroon","juz":18,"page":346},{"s":23,"a":68,"key":"23:68","ar":"أَفَلَمْ يَدَّبَّرُوا۟ ٱلْقَوْلَ أَمْ جَآءَهُم مَّا لَمْ يَأْتِ ءَابَآءَهُمُ ٱلْأَوَّلِينَ","en":"Then have they not reflected over the word [i.e., the Qur’ān], or has there come to them that which had not come to their forefathers?","tr":"Afalam yaddabbaroo alqawla am jaahumma lam ya/ti abaahumu al-awwaleen","juz":18,"page":346},{"s":23,"a":69,"key":"23:69","ar":"أَمْ لَمْ يَعْرِفُوا۟ رَسُولَهُمْ فَهُمْ لَهُۥ مُنكِرُونَ","en":"Or did they not know their Messenger, so they are toward him disacknowledging?","tr":"Am lam yaAArifoo rasoolahum fahum lahumunkiroon","juz":18,"page":346},{"s":23,"a":70,"key":"23:70","ar":"أَمْ يَقُولُونَ بِهِۦ جِنَّةٌۢ ۚ بَلْ جَآءَهُم بِٱلْحَقِّ وَأَكْثَرُهُمْ لِلْحَقِّ كَـٰرِهُونَ","en":"Or do they say, \"In him is madness\"? Rather, he brought them the truth, but most of them, to the truth, are averse.","tr":"Am yaqooloona bihi jinnatun bal jaahumbilhaqqi waaktharuhum lilhaqqi karihoon","juz":18,"page":346},{"s":23,"a":71,"key":"23:71","ar":"وَلَوِ ٱتَّبَعَ ٱلْحَقُّ أَهْوَآءَهُمْ لَفَسَدَتِ ٱلسَّمَـٰوَٰتُ وَٱلْأَرْضُ وَمَن فِيهِنَّ ۚ بَلْ أَتَيْنَـٰهُم بِذِكْرِهِمْ فَهُمْ عَن ذِكْرِهِم مُّعْرِضُونَ","en":"But if the Truth [i.e., Allāh] had followed their inclinations, the heavens and the earth and whoever is in them would have been ruined. Rather, We have brought them their message,1 but they, from their message, are turning away.","tr":"Walawi ittabaAAa alhaqqu ahwaahumlafasadati assamawatu wal-arduwaman feehinna bal ataynahum bithikrihim fahum AAanthikrihim muAAridoon","juz":18,"page":346},{"s":23,"a":72,"key":"23:72","ar":"أَمْ تَسْـَٔلُهُمْ خَرْجًا فَخَرَاجُ رَبِّكَ خَيْرٌ ۖ وَهُوَ خَيْرُ ٱلرَّٰزِقِينَ","en":"Or do you, [O Muḥammad], ask them for payment? But the reward of your Lord is best, and He is the best of providers.","tr":"Am tas-aluhum kharjan fakharajurabbika khayrun wahuwa khayru arraziqeen","juz":18,"page":346},{"s":23,"a":73,"key":"23:73","ar":"وَإِنَّكَ لَتَدْعُوهُمْ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"And indeed, you invite them to a straight path.","tr":"Wa-innaka latadAAoohum ila siratinmustaqeem","juz":18,"page":346},{"s":23,"a":74,"key":"23:74","ar":"وَإِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ عَنِ ٱلصِّرَٰطِ لَنَـٰكِبُونَ","en":"But indeed, those who do not believe in the Hereafter are deviating from the path.","tr":"Wa-inna allatheena layu/minoona bil-akhirati AAani assiratilanakiboon","juz":18,"page":346},{"s":23,"a":75,"key":"23:75","ar":"۞ وَلَوْ رَحِمْنَـٰهُمْ وَكَشَفْنَا مَا بِهِم مِّن ضُرٍّ لَّلَجُّوا۟ فِى طُغْيَـٰنِهِمْ يَعْمَهُونَ","en":"And even if We gave them mercy and removed what was upon them of affliction, they would persist in their transgression, wandering blindly.","tr":"Walaw rahimnahum wakashafnama bihim min durrin lalajjoo fee tughyanihimyaAAmahoon","juz":18,"page":347},{"s":23,"a":76,"key":"23:76","ar":"وَلَقَدْ أَخَذْنَـٰهُم بِٱلْعَذَابِ فَمَا ٱسْتَكَانُوا۟ لِرَبِّهِمْ وَمَا يَتَضَرَّعُونَ","en":"And We had gripped them with suffering [as a warning], but they did not yield to their Lord, nor did they humbly supplicate, [and will continue thus]","tr":"Walaqad akhathnahum bilAAathabifama istakanoo lirabbihim wama yatadarraAAoon","juz":18,"page":347},{"s":23,"a":77,"key":"23:77","ar":"حَتَّىٰٓ إِذَا فَتَحْنَا عَلَيْهِم بَابًا ذَا عَذَابٍ شَدِيدٍ إِذَا هُمْ فِيهِ مُبْلِسُونَ","en":"Until when We have opened before them a door of severe punishment, immediately they will be therein in despair.","tr":"Hatta itha fatahnaAAalayhim baban tha AAathabin shadeedin ithahum feehi mublisoon","juz":18,"page":347},{"s":23,"a":78,"key":"23:78","ar":"وَهُوَ ٱلَّذِىٓ أَنشَأَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَـٰرَ وَٱلْأَفْـِٔدَةَ ۚ قَلِيلًا مَّا تَشْكُرُونَ","en":"And it is He who produced for you hearing and vision and hearts [i.e., intellect]; little are you grateful.","tr":"Wahuwa allathee anshaa lakumu assamAAawal-absara wal-af-idata qaleelan matashkuroon","juz":18,"page":347},{"s":23,"a":79,"key":"23:79","ar":"وَهُوَ ٱلَّذِى ذَرَأَكُمْ فِى ٱلْأَرْضِ وَإِلَيْهِ تُحْشَرُونَ","en":"And it is He who has multiplied you throughout the earth, and to Him you will be gathered.","tr":"Wahuwa allathee tharaakum feeal-ardi wa-ilayhi tuhsharoon","juz":18,"page":347},{"s":23,"a":80,"key":"23:80","ar":"وَهُوَ ٱلَّذِى يُحْىِۦ وَيُمِيتُ وَلَهُ ٱخْتِلَـٰفُ ٱلَّيْلِ وَٱلنَّهَارِ ۚ أَفَلَا تَعْقِلُونَ","en":"And it is He who gives life and causes death, and His is the alternation of the night and the day. Then will you not reason?","tr":"Wahuwa allathee yuhyeewayumeetu walahu ikhtilafu allayli wannahariafala taAAqiloon","juz":18,"page":347},{"s":23,"a":81,"key":"23:81","ar":"بَلْ قَالُوا۟ مِثْلَ مَا قَالَ ٱلْأَوَّلُونَ","en":"Rather,1 they say like what the former peoples said.","tr":"Bal qaloo mithla ma qalaal-awwaloon","juz":18,"page":347},{"s":23,"a":82,"key":"23:82","ar":"قَالُوٓا۟ أَءِذَا مِتْنَا وَكُنَّا تُرَابًا وَعِظَـٰمًا أَءِنَّا لَمَبْعُوثُونَ","en":"They said, \"When we have died and become dust and bones, are we indeed to be resurrected?","tr":"Qaloo a-itha mitnawakunna turaban waAAithamana-inna lamabAAoothoon","juz":18,"page":347},{"s":23,"a":83,"key":"23:83","ar":"لَقَدْ وُعِدْنَا نَحْنُ وَءَابَآؤُنَا هَـٰذَا مِن قَبْلُ إِنْ هَـٰذَآ إِلَّآ أَسَـٰطِيرُ ٱلْأَوَّلِينَ","en":"We have been promised this, we and our forefathers, before; this is not but legends of the former peoples.\"","tr":"Laqad wuAAidna nahnu waabaonahatha min qablu in hatha illa asateerual-awwaleen","juz":18,"page":347},{"s":23,"a":84,"key":"23:84","ar":"قُل لِّمَنِ ٱلْأَرْضُ وَمَن فِيهَآ إِن كُنتُمْ تَعْلَمُونَ","en":"Say, [O Muḥammad], \"To whom belongs the earth and whoever is in it, if you should know?\"","tr":"Qul limani al-ardu waman feehain kuntum taAAlamoon","juz":18,"page":347},{"s":23,"a":85,"key":"23:85","ar":"سَيَقُولُونَ لِلَّهِ ۚ قُلْ أَفَلَا تَذَكَّرُونَ","en":"They will say, \"To Allāh.\" Say, \"Then will you not remember?\"","tr":"Sayaqooloona lillahi qul afalatathakkaroon","juz":18,"page":347},{"s":23,"a":86,"key":"23:86","ar":"قُلْ مَن رَّبُّ ٱلسَّمَـٰوَٰتِ ٱلسَّبْعِ وَرَبُّ ٱلْعَرْشِ ٱلْعَظِيمِ","en":"Say, \"Who is Lord of the seven heavens and Lord of the Great Throne?\"","tr":"Qul man rabbu assamawatiassabAAi warabbu alAAarshi alAAatheem","juz":18,"page":347},{"s":23,"a":87,"key":"23:87","ar":"سَيَقُولُونَ لِلَّهِ ۚ قُلْ أَفَلَا تَتَّقُونَ","en":"They will say, \"[They belong] to Allāh.\" Say, \"Then will you not fear Him?\"","tr":"Sayaqooloona lillahi qul afalatattaqoon","juz":18,"page":347},{"s":23,"a":88,"key":"23:88","ar":"قُلْ مَنۢ بِيَدِهِۦ مَلَكُوتُ كُلِّ شَىْءٍ وَهُوَ يُجِيرُ وَلَا يُجَارُ عَلَيْهِ إِن كُنتُمْ تَعْلَمُونَ","en":"Say, \"In whose hand is the realm of all things - and He protects while none can protect against Him - if you should know?\"","tr":"Qul man biyadihi malakootu kulli shay-inwahuwa yujeeru wala yujaru AAalayhi in kuntumtaAAlamoon","juz":18,"page":347},{"s":23,"a":89,"key":"23:89","ar":"سَيَقُولُونَ لِلَّهِ ۚ قُلْ فَأَنَّىٰ تُسْحَرُونَ","en":"They will say, \"[All belongs] to Allāh.\" Say, \"Then how are you deluded?\"","tr":"Sayaqooloona lillahi qul faannatusharoon","juz":18,"page":347},{"s":23,"a":90,"key":"23:90","ar":"بَلْ أَتَيْنَـٰهُم بِٱلْحَقِّ وَإِنَّهُمْ لَكَـٰذِبُونَ","en":"Rather, We have brought them the truth, and indeed they are liars.","tr":"Bal ataynahum bilhaqqiwa-innahum lakathiboon","juz":18,"page":348},{"s":23,"a":91,"key":"23:91","ar":"مَا ٱتَّخَذَ ٱللَّهُ مِن وَلَدٍ وَمَا كَانَ مَعَهُۥ مِنْ إِلَـٰهٍ ۚ إِذًا لَّذَهَبَ كُلُّ إِلَـٰهٍۭ بِمَا خَلَقَ وَلَعَلَا بَعْضُهُمْ عَلَىٰ بَعْضٍ ۚ سُبْحَـٰنَ ٱللَّهِ عَمَّا يَصِفُونَ","en":"Allāh has not taken any son, nor has there ever been with Him any deity. [If there had been], then each deity would have taken what it created, and some of them would have [sought to] overcome others. Exalted is Allāh above what they describe [concerning Him].","tr":"Ma ittakhatha Allahumin waladin wama kana maAAahu min ilahin ithanlathahaba kullu ilahin bima khalaqa walaAAalabaAAduhum AAala baAAdin subhana AllahiAAamma yasifoon","juz":18,"page":348},{"s":23,"a":92,"key":"23:92","ar":"عَـٰلِمِ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ فَتَعَـٰلَىٰ عَمَّا يُشْرِكُونَ","en":"[He is] Knower of the unseen and the witnessed, so high is He above what they associate [with Him].","tr":"AAalimi alghaybi washshahadatifataAAala AAamma yushrikoon","juz":18,"page":348},{"s":23,"a":93,"key":"23:93","ar":"قُل رَّبِّ إِمَّا تُرِيَنِّى مَا يُوعَدُونَ","en":"Say, [O Muḥammad], \"My Lord, if You should show me that which they are promised,","tr":"Qul rabbi imma turiyannee mayooAAadoon","juz":18,"page":348},{"s":23,"a":94,"key":"23:94","ar":"رَبِّ فَلَا تَجْعَلْنِى فِى ٱلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"My Lord, then do not place me among the wrongdoing people.\"","tr":"Rabbi fala tajAAalnee fee alqawmi aththalimeen","juz":18,"page":348},{"s":23,"a":95,"key":"23:95","ar":"وَإِنَّا عَلَىٰٓ أَن نُّرِيَكَ مَا نَعِدُهُمْ لَقَـٰدِرُونَ","en":"And indeed, We are Able to show you what We have promised them.","tr":"Wa-inna AAala an nuriyaka manaAAiduhum laqadiroon","juz":18,"page":348},{"s":23,"a":96,"key":"23:96","ar":"ٱدْفَعْ بِٱلَّتِى هِىَ أَحْسَنُ ٱلسَّيِّئَةَ ۚ نَحْنُ أَعْلَمُ بِمَا يَصِفُونَ","en":"Repel, by [means of] what is best, [their] evil. We are most knowing of what they describe.","tr":"IdfaAA billatee hiya ahsanu assayyi-atanahnu aAAlamu bima yasifoon","juz":18,"page":348},{"s":23,"a":97,"key":"23:97","ar":"وَقُل رَّبِّ أَعُوذُ بِكَ مِنْ هَمَزَٰتِ ٱلشَّيَـٰطِينِ","en":"And say, \"My Lord, I seek refuge in You from the incitements of the devils,","tr":"Waqul rabbi aAAoothu bika min hamazatiashshayateen","juz":18,"page":348},{"s":23,"a":98,"key":"23:98","ar":"وَأَعُوذُ بِكَ رَبِّ أَن يَحْضُرُونِ","en":"And I seek refuge in You, my Lord, lest they be present with me.\"","tr":"WaaAAoothu bika rabbi an yahduroon","juz":18,"page":348},{"s":23,"a":99,"key":"23:99","ar":"حَتَّىٰٓ إِذَا جَآءَ أَحَدَهُمُ ٱلْمَوْتُ قَالَ رَبِّ ٱرْجِعُونِ","en":"[For such is the state of the disbelievers] until, when death comes to one of them, he says, \"My Lord, send me back","tr":"Hatta itha jaa ahadahumualmawtu qala rabbi irjiAAoon","juz":18,"page":348},{"s":23,"a":100,"key":"23:100","ar":"لَعَلِّىٓ أَعْمَلُ صَـٰلِحًا فِيمَا تَرَكْتُ ۚ كَلَّآ ۚ إِنَّهَا كَلِمَةٌ هُوَ قَآئِلُهَا ۖ وَمِن وَرَآئِهِم بَرْزَخٌ إِلَىٰ يَوْمِ يُبْعَثُونَ","en":"That I might do righteousness in that which I left behind.\"1 No! It is only a word he is saying; and behind them is a barrier until the Day they are resurrected.","tr":"LaAAallee aAAmalu salihanfeema taraktu kalla innaha kalimatun huwa qa-iluhawamin wara-ihim barzakhun ila yawmi yubAAathoon","juz":18,"page":348},{"s":23,"a":101,"key":"23:101","ar":"فَإِذَا نُفِخَ فِى ٱلصُّورِ فَلَآ أَنسَابَ بَيْنَهُمْ يَوْمَئِذٍ وَلَا يَتَسَآءَلُونَ","en":"So when the Horn is blown, no relationship will there be among them that Day, nor will they ask about one another.","tr":"Fa-itha nufikha fee assoorifala ansaba baynahum yawma-ithin walayatasaaloon","juz":18,"page":348},{"s":23,"a":102,"key":"23:102","ar":"فَمَن ثَقُلَتْ مَوَٰزِينُهُۥ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"And those whose scales are heavy [with good deeds] - it is they who are the successful.","tr":"Faman thaqulat mawazeenuhu faola-ikahumu almuflihoon","juz":18,"page":348},{"s":23,"a":103,"key":"23:103","ar":"وَمَنْ خَفَّتْ مَوَٰزِينُهُۥ فَأُو۟لَـٰٓئِكَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ فِى جَهَنَّمَ خَـٰلِدُونَ","en":"But those whose scales are light - those are the ones who have lost their souls, [being] in Hell, abiding eternally.","tr":"Waman khaffat mawazeenuhu faola-ikaallatheena khasiroo anfusahum fee jahannama khalidoon","juz":18,"page":348},{"s":23,"a":104,"key":"23:104","ar":"تَلْفَحُ وُجُوهَهُمُ ٱلنَّارُ وَهُمْ فِيهَا كَـٰلِحُونَ","en":"The Fire will sear their faces, and they therein will have taut smiles.1","tr":"Talfahu wujoohahumu annaruwahum feeha kalihoon","juz":18,"page":348},{"s":23,"a":105,"key":"23:105","ar":"أَلَمْ تَكُنْ ءَايَـٰتِى تُتْلَىٰ عَلَيْكُمْ فَكُنتُم بِهَا تُكَذِّبُونَ","en":"[It will be said], \"Were not My verses recited to you and you used to deny them?\"","tr":"Alam takun ayatee tutlaAAalaykum fakuntum biha tukaththiboon","juz":18,"page":349},{"s":23,"a":106,"key":"23:106","ar":"قَالُوا۟ رَبَّنَا غَلَبَتْ عَلَيْنَا شِقْوَتُنَا وَكُنَّا قَوْمًا ضَآلِّينَ","en":"They will say, \"Our Lord, our wretchedness overcame us, and we were a people astray.","tr":"Qaloo rabbana ghalabatAAalayna shiqwatuna wakunna qawman dalleen","juz":18,"page":349},{"s":23,"a":107,"key":"23:107","ar":"رَبَّنَآ أَخْرِجْنَا مِنْهَا فَإِنْ عُدْنَا فَإِنَّا ظَـٰلِمُونَ","en":"Our Lord, remove us from it, and if we were to return [to evil], we would indeed be wrongdoers.\"","tr":"Rabbana akhrijna minhafa-in AAudna fa-inna thalimoon","juz":18,"page":349},{"s":23,"a":108,"key":"23:108","ar":"قَالَ ٱخْسَـُٔوا۟ فِيهَا وَلَا تُكَلِّمُونِ","en":"He will say, \"Remain despised therein and do not speak to Me.","tr":"Qala ikhsaoo feeha walatukallimoon","juz":18,"page":349},{"s":23,"a":109,"key":"23:109","ar":"إِنَّهُۥ كَانَ فَرِيقٌ مِّنْ عِبَادِى يَقُولُونَ رَبَّنَآ ءَامَنَّا فَٱغْفِرْ لَنَا وَٱرْحَمْنَا وَأَنتَ خَيْرُ ٱلرَّٰحِمِينَ","en":"Indeed, there was a party of My servants who said, 'Our Lord, we have believed, so forgive us and have mercy upon us, and You are the best of the merciful.'","tr":"Innahu kana fareequn min AAibadeeyaqooloona rabbana amanna faghfirlana warhamna waanta khayru arrahimeen","juz":18,"page":349},{"s":23,"a":110,"key":"23:110","ar":"فَٱتَّخَذْتُمُوهُمْ سِخْرِيًّا حَتَّىٰٓ أَنسَوْكُمْ ذِكْرِى وَكُنتُم مِّنْهُمْ تَضْحَكُونَ","en":"But you took them in mockery to the point that they made you forget My remembrance, and you used to laugh at them.","tr":"Fattakhathtumoohumsikhriyyan hatta ansawkum thikree wakuntumminhum tadhakoon","juz":18,"page":349},{"s":23,"a":111,"key":"23:111","ar":"إِنِّى جَزَيْتُهُمُ ٱلْيَوْمَ بِمَا صَبَرُوٓا۟ أَنَّهُمْ هُمُ ٱلْفَآئِزُونَ","en":"Indeed, I have rewarded them this Day for their patient endurance - that they are the attainers [of success].\"","tr":"Innee jazaytuhumu alyawma bima sabarooannahum humu alfa-izoon","juz":18,"page":349},{"s":23,"a":112,"key":"23:112","ar":"قَـٰلَ كَمْ لَبِثْتُمْ فِى ٱلْأَرْضِ عَدَدَ سِنِينَ","en":"[Allāh] will say, \"How long did you remain on earth in number of years?\"","tr":"Qala kam labithtum fee al-ardiAAadada sineen","juz":18,"page":349},{"s":23,"a":113,"key":"23:113","ar":"قَالُوا۟ لَبِثْنَا يَوْمًا أَوْ بَعْضَ يَوْمٍ فَسْـَٔلِ ٱلْعَآدِّينَ","en":"They will say, \"We remained a day or part of a day; ask those who enumerate.\"","tr":"Qaloo labithna yawman aw baAAdayawmin fas-ali alAAaddeen","juz":18,"page":349},{"s":23,"a":114,"key":"23:114","ar":"قَـٰلَ إِن لَّبِثْتُمْ إِلَّا قَلِيلًا ۖ لَّوْ أَنَّكُمْ كُنتُمْ تَعْلَمُونَ","en":"He will say, \"You stayed not but a little - if only you had known.","tr":"Qala in labithtum illaqaleelan law annakum kuntum taAAlamoon","juz":18,"page":349},{"s":23,"a":115,"key":"23:115","ar":"أَفَحَسِبْتُمْ أَنَّمَا خَلَقْنَـٰكُمْ عَبَثًا وَأَنَّكُمْ إِلَيْنَا لَا تُرْجَعُونَ","en":"Then did you think that We created you uselessly and that to Us you would not be returned?\"","tr":"Afahasibtum annama khalaqnakumAAabathan waannakum ilayna la turjaAAoon","juz":18,"page":349},{"s":23,"a":116,"key":"23:116","ar":"فَتَعَـٰلَى ٱللَّهُ ٱلْمَلِكُ ٱلْحَقُّ ۖ لَآ إِلَـٰهَ إِلَّا هُوَ رَبُّ ٱلْعَرْشِ ٱلْكَرِيمِ","en":"So exalted is Allāh, the Sovereign,1 the Truth;2 there is no deity except Him, Lord of the Noble Throne.","tr":"FataAAala Allahualmaliku alhaqqu la ilaha illa huwarabbu alAAarshi alkareem","juz":18,"page":349},{"s":23,"a":117,"key":"23:117","ar":"وَمَن يَدْعُ مَعَ ٱللَّهِ إِلَـٰهًا ءَاخَرَ لَا بُرْهَـٰنَ لَهُۥ بِهِۦ فَإِنَّمَا حِسَابُهُۥ عِندَ رَبِّهِۦٓ ۚ إِنَّهُۥ لَا يُفْلِحُ ٱلْكَـٰفِرُونَ","en":"And whoever invokes besides Allāh another deity for which he has no proof - then his account is only with his Lord. Indeed, the disbelievers will not succeed.","tr":"Waman yadAAu maAAa Allahi ilahanakhara la burhana lahu bihi fa-innamahisabuhu AAinda rabbihi innahu la yuflihualkafiroon","juz":18,"page":349},{"s":23,"a":118,"key":"23:118","ar":"وَقُل رَّبِّ ٱغْفِرْ وَٱرْحَمْ وَأَنتَ خَيْرُ ٱلرَّٰحِمِينَ","en":"And, [O Muḥammad], say, \"My Lord, forgive and have mercy, and You are the best of the merciful.\"","tr":"Waqul rabbi ighfir warhamwaanta khayru arrahimeen","juz":18,"page":349},{"s":24,"a":1,"key":"24:1","ar":" سُورَةٌ أَنزَلْنَـٰهَا وَفَرَضْنَـٰهَا وَأَنزَلْنَا فِيهَآ ءَايَـٰتٍۭ بَيِّنَـٰتٍ لَّعَلَّكُمْ تَذَكَّرُونَ","en":"[This is] a sūrah which We have sent down and made [that within it] obligatory and revealed therein verses of clear evidence that you might remember.","tr":"Sooratun anzalnaha wafaradnahawaanzalna feeha ayatin bayyinatinlaAAallakum tathakkaroon","juz":18,"page":350},{"s":24,"a":2,"key":"24:2","ar":"ٱلزَّانِيَةُ وَٱلزَّانِى فَٱجْلِدُوا۟ كُلَّ وَٰحِدٍ مِّنْهُمَا مِا۟ئَةَ جَلْدَةٍ ۖ وَلَا تَأْخُذْكُم بِهِمَا رَأْفَةٌ فِى دِينِ ٱللَّهِ إِن كُنتُمْ تُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ ۖ وَلْيَشْهَدْ عَذَابَهُمَا طَآئِفَةٌ مِّنَ ٱلْمُؤْمِنِينَ","en":"The [unmarried] woman or [unmarried] man found guilty of sexual intercourse1 - lash each one of them with a hundred lashes,2 and do not be taken by pity for them in the religion [i.e., law] of Allāh,3 if you should believe in Allāh and the Last Day. And let a group of the believers witness their punishment.","tr":"Azzaniyatu wazzaneefajlidoo kulla wahidin minhuma mi-atajaldatin wala ta/khuthkum bihima ra/fatunfee deeni Allahi in kuntum tu/minoona billahiwalyawmi al-akhiri walyashhad AAathabahumata-ifatun mina almu/mineen","juz":18,"page":350},{"s":24,"a":3,"key":"24:3","ar":"ٱلزَّانِى لَا يَنكِحُ إِلَّا زَانِيَةً أَوْ مُشْرِكَةً وَٱلزَّانِيَةُ لَا يَنكِحُهَآ إِلَّا زَانٍ أَوْ مُشْرِكٌ ۚ وَحُرِّمَ ذَٰلِكَ عَلَى ٱلْمُؤْمِنِينَ","en":"The fornicator does not marry except a [female] fornicator or polytheist, and none marries her except a fornicator1 or a polytheist, and that [i.e., marriage to such persons] has been made unlawful to the believers.","tr":"Azzanee la yankihuilla zaniyatan aw mushrikatan wazzaniyatula yankihuha illa zanin awmushrikun wahurrima thalika AAalaalmu/mineen","juz":18,"page":350},{"s":24,"a":4,"key":"24:4","ar":"وَٱلَّذِينَ يَرْمُونَ ٱلْمُحْصَنَـٰتِ ثُمَّ لَمْ يَأْتُوا۟ بِأَرْبَعَةِ شُهَدَآءَ فَٱجْلِدُوهُمْ ثَمَـٰنِينَ جَلْدَةً وَلَا تَقْبَلُوا۟ لَهُمْ شَهَـٰدَةً أَبَدًا ۚ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ","en":"And those who accuse chaste women and then do not produce four witnesses - lash them with eighty lashes and do not accept from them testimony ever after. And those are the defiantly disobedient,","tr":"Wallatheena yarmoona almuhsanatithumma lam ya/too bi-arbaAAati shuhadaa fajlidoohumthamaneena jaldatan wala taqbaloo lahum shahadatanabadan waola-ika humu alfasiqoon","juz":18,"page":350},{"s":24,"a":5,"key":"24:5","ar":"إِلَّا ٱلَّذِينَ تَابُوا۟ مِنۢ بَعْدِ ذَٰلِكَ وَأَصْلَحُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"Except for those who repent thereafter and reform, for indeed, Allāh is Forgiving and Merciful.","tr":"Illa allatheena taboomin baAAdi thalika waaslahoo fa-inna Allahaghafoorun raheem","juz":18,"page":350},{"s":24,"a":6,"key":"24:6","ar":"وَٱلَّذِينَ يَرْمُونَ أَزْوَٰجَهُمْ وَلَمْ يَكُن لَّهُمْ شُهَدَآءُ إِلَّآ أَنفُسُهُمْ فَشَهَـٰدَةُ أَحَدِهِمْ أَرْبَعُ شَهَـٰدَٰتٍۭ بِٱللَّهِ ۙ إِنَّهُۥ لَمِنَ ٱلصَّـٰدِقِينَ","en":"And those who accuse their wives [of adultery] and have no witnesses except themselves - then the witness of one of them1 [shall be] four testimonies [swearing] by Allāh that indeed, he is of the truthful.","tr":"Wallatheena yarmoona azwajahumwalam yakun lahum shuhadao illa anfusuhum fashahadatuahadihim arbaAAu shahadatin billahiinnahu lamina assadiqeen","juz":18,"page":350},{"s":24,"a":7,"key":"24:7","ar":"وَٱلْخَـٰمِسَةُ أَنَّ لَعْنَتَ ٱللَّهِ عَلَيْهِ إِن كَانَ مِنَ ٱلْكَـٰذِبِينَ","en":"And the fifth [oath will be] that the curse of Allāh be upon him if he should be of the liars.","tr":"Walkhamisatu anna laAAnata AllahiAAalayhi in kana mina alkathibeen","juz":18,"page":350},{"s":24,"a":8,"key":"24:8","ar":"وَيَدْرَؤُا۟ عَنْهَا ٱلْعَذَابَ أَن تَشْهَدَ أَرْبَعَ شَهَـٰدَٰتٍۭ بِٱللَّهِ ۙ إِنَّهُۥ لَمِنَ ٱلْكَـٰذِبِينَ","en":"But it will prevent punishment from her if she gives four testimonies [swearing] by Allāh that indeed, he is of the liars.","tr":"Wayadrao AAanha alAAathaba antashhada arbaAAa shahadatin billahiinnahu lamina alkathibeen","juz":18,"page":350},{"s":24,"a":9,"key":"24:9","ar":"وَٱلْخَـٰمِسَةَ أَنَّ غَضَبَ ٱللَّهِ عَلَيْهَآ إِن كَانَ مِنَ ٱلصَّـٰدِقِينَ","en":"And the fifth [oath will be] that the wrath of Allāh be upon her if he was of the truthful.","tr":"Walkhamisata anna ghadabaAllahi AAalayha in kana mina assadiqeen","juz":18,"page":350},{"s":24,"a":10,"key":"24:10","ar":"وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ وَأَنَّ ٱللَّهَ تَوَّابٌ حَكِيمٌ","en":"And if not for the favor of Allāh upon you and His mercy...1 and because Allāh is Accepting of Repentance and Wise.","tr":"Walawla fadlu AllahiAAalaykum warahmatuhu waanna Allaha tawwabunhakeem","juz":18,"page":350},{"s":24,"a":11,"key":"24:11","ar":"إِنَّ ٱلَّذِينَ جَآءُو بِٱلْإِفْكِ عُصْبَةٌ مِّنكُمْ ۚ لَا تَحْسَبُوهُ شَرًّا لَّكُم ۖ بَلْ هُوَ خَيْرٌ لَّكُمْ ۚ لِكُلِّ ٱمْرِئٍ مِّنْهُم مَّا ٱكْتَسَبَ مِنَ ٱلْإِثْمِ ۚ وَٱلَّذِى تَوَلَّىٰ كِبْرَهُۥ مِنْهُمْ لَهُۥ عَذَابٌ عَظِيمٌ","en":"Indeed, those who came with falsehood1 are a group among you. Do not think it bad for you; rather, it is good for you. For every person among them is what [punishment] he has earned from the sin, and he who took upon himself the greater portion thereof2 - for him is a great punishment [i.e., Hellfire].","tr":"Inna allatheena jaoo bil-ifkiAAusbatun minkum la tahsaboohu sharran lakumbal huwa khayrun lakum likulli imri-in minhum ma iktasabamina al-ithmi wallathee tawalla kibrahuminhum lahu AAathabun AAatheem","juz":18,"page":351},{"s":24,"a":12,"key":"24:12","ar":"لَّوْلَآ إِذْ سَمِعْتُمُوهُ ظَنَّ ٱلْمُؤْمِنُونَ وَٱلْمُؤْمِنَـٰتُ بِأَنفُسِهِمْ خَيْرًا وَقَالُوا۟ هَـٰذَآ إِفْكٌ مُّبِينٌ","en":"Why, when you heard it, did not the believing men and believing women think good of themselves [i.e., one another] and say, \"This is an obvious falsehood\"?","tr":"Lawla ith samiAAtumoohu thannaalmu/minoona walmu/minatu bi-anfusihim khayran waqaloohatha ifkun mubeen","juz":18,"page":351},{"s":24,"a":13,"key":"24:13","ar":"لَّوْلَا جَآءُو عَلَيْهِ بِأَرْبَعَةِ شُهَدَآءَ ۚ فَإِذْ لَمْ يَأْتُوا۟ بِٱلشُّهَدَآءِ فَأُو۟لَـٰٓئِكَ عِندَ ٱللَّهِ هُمُ ٱلْكَـٰذِبُونَ","en":"Why did they [who slandered] not produce for it four witnesses? And when they do not produce the witnesses, then it is they, in the sight of Allāh, who are the liars.","tr":"Lawla jaoo AAalayhibi-arbaAAati shuhadaa fa-ith lam ya/too bishshuhada-ifaola-ika AAinda Allahi humu alkathiboon","juz":18,"page":351},{"s":24,"a":14,"key":"24:14","ar":"وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ لَمَسَّكُمْ فِى مَآ أَفَضْتُمْ فِيهِ عَذَابٌ عَظِيمٌ","en":"And if it had not been for the favor of Allāh upon you and His mercy in this world and the Hereafter, you would have been touched for that [lie] in which you were involved by a great punishment","tr":"Walawla fadlu AllahiAAalaykum warahmatuhu fee addunya wal-akhiratilamassakum fee ma afadtum feehi AAathabunAAatheem","juz":18,"page":351},{"s":24,"a":15,"key":"24:15","ar":"إِذْ تَلَقَّوْنَهُۥ بِأَلْسِنَتِكُمْ وَتَقُولُونَ بِأَفْوَاهِكُم مَّا لَيْسَ لَكُم بِهِۦ عِلْمٌ وَتَحْسَبُونَهُۥ هَيِّنًا وَهُوَ عِندَ ٱللَّهِ عَظِيمٌ","en":"When you received it with your tongues1 and said with your mouths that of which you had no knowledge and thought it was insignificant while it was, in the sight of Allāh, tremendous.","tr":"Ith talaqqawnahu bi-alsinatikumwataqooloona bi-afwahikum ma laysa lakum bihiAAilmun watahsaboonahu hayyinan wahuwa AAinda AllahiAAatheem","juz":18,"page":351},{"s":24,"a":16,"key":"24:16","ar":"وَلَوْلَآ إِذْ سَمِعْتُمُوهُ قُلْتُم مَّا يَكُونُ لَنَآ أَن نَّتَكَلَّمَ بِهَـٰذَا سُبْحَـٰنَكَ هَـٰذَا بُهْتَـٰنٌ عَظِيمٌ","en":"And why, when you heard it, did you not say, \"It is not for us to speak of this. Exalted are You, [O Allāh]; this is a great slander\"?","tr":"Walawla ith samiAAtumoohuqultum ma yakoonu lana an natakallama bihathasubhanaka hatha buhtanun AAatheem","juz":18,"page":351},{"s":24,"a":17,"key":"24:17","ar":"يَعِظُكُمُ ٱللَّهُ أَن تَعُودُوا۟ لِمِثْلِهِۦٓ أَبَدًا إِن كُنتُم مُّؤْمِنِينَ","en":"Allāh warns you against returning to the likes of this [conduct], ever, if you should be believers.","tr":"YaAAithukumu Allahu antaAAoodoo limithlihi abadan in kuntum mu/mineen","juz":18,"page":351},{"s":24,"a":18,"key":"24:18","ar":"وَيُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْـَٔايَـٰتِ ۚ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"And Allāh makes clear to you the verses [i.e., His rulings], and Allāh is Knowing and Wise.","tr":"Wayubayyinu Allahu lakumu al-ayatiwallahu AAaleemun hakeem","juz":18,"page":351},{"s":24,"a":19,"key":"24:19","ar":"إِنَّ ٱلَّذِينَ يُحِبُّونَ أَن تَشِيعَ ٱلْفَـٰحِشَةُ فِى ٱلَّذِينَ ءَامَنُوا۟ لَهُمْ عَذَابٌ أَلِيمٌ فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ ۚ وَٱللَّهُ يَعْلَمُ وَأَنتُمْ لَا تَعْلَمُونَ","en":"Indeed, those who like that immorality1 should be spread [or publicized] among those who have believed will have a painful punishment in this world and the Hereafter. And Allāh knows2 and you do not know.","tr":"Inna allatheena yuhibboona antasheeAAa alfahishatu fee allatheena amanoolahum AAathabun aleemun fee addunya wal-akhiratiwallahu yaAAlamu waantum la taAAlamoon","juz":18,"page":351},{"s":24,"a":20,"key":"24:20","ar":"وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ وَأَنَّ ٱللَّهَ رَءُوفٌ رَّحِيمٌ","en":"And if it had not been for the favor of Allāh upon you and His mercy...1 and because Allāh is Kind and Merciful.","tr":"Walawla fadlu AllahiAAalaykum warahmatuhu waanna Allaha raoofun raheem","juz":18,"page":351},{"s":24,"a":21,"key":"24:21","ar":"۞ يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّبِعُوا۟ خُطُوَٰتِ ٱلشَّيْطَـٰنِ ۚ وَمَن يَتَّبِعْ خُطُوَٰتِ ٱلشَّيْطَـٰنِ فَإِنَّهُۥ يَأْمُرُ بِٱلْفَحْشَآءِ وَٱلْمُنكَرِ ۚ وَلَوْلَا فَضْلُ ٱللَّهِ عَلَيْكُمْ وَرَحْمَتُهُۥ مَا زَكَىٰ مِنكُم مِّنْ أَحَدٍ أَبَدًا وَلَـٰكِنَّ ٱللَّهَ يُزَكِّى مَن يَشَآءُ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ","en":"O you who have believed, do not follow the footsteps of Satan. And whoever follows the footsteps of Satan - indeed, he enjoins immorality and wrongdoing. And if not for the favor of Allāh upon you and His mercy, not one of you would have been pure, ever, but Allāh purifies whom He wills, and Allāh is Hearing and Knowing.","tr":"Ya ayyuha allatheena amanoola tattabiAAoo khutuwati ashshaytaniwaman yattabiAA khutuwati ashshaytanifa-innahu ya/muru bilfahsha-i walmunkariwalawla fadlu Allahi AAalaykum warahmatuhuma zaka minkum min ahadin abadan walakinnaAllaha yuzakkee man yashao wallahusameeAAun AAaleem","juz":18,"page":352},{"s":24,"a":22,"key":"24:22","ar":"وَلَا يَأْتَلِ أُو۟لُوا۟ ٱلْفَضْلِ مِنكُمْ وَٱلسَّعَةِ أَن يُؤْتُوٓا۟ أُو۟لِى ٱلْقُرْبَىٰ وَٱلْمَسَـٰكِينَ وَٱلْمُهَـٰجِرِينَ فِى سَبِيلِ ٱللَّهِ ۖ وَلْيَعْفُوا۟ وَلْيَصْفَحُوٓا۟ ۗ أَلَا تُحِبُّونَ أَن يَغْفِرَ ٱللَّهُ لَكُمْ ۗ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"And let not those of virtue among you and wealth swear not to give [aid] to their relatives and the needy and the emigrants for the cause of Allāh, and let them pardon and overlook. Would you not like that Allāh should forgive you? And Allāh is Forgiving and Merciful.","tr":"Wala ya/tali oloo alfadliminkum wassaAAati an yu/too olee alqurba walmasakeenawalmuhajireena fee sabeeli AllahiwalyaAAfoo walyasfahoo ala tuhibboonaan yaghfira Allahu lakum wallahu ghafoorunraheem","juz":18,"page":352},{"s":24,"a":23,"key":"24:23","ar":"إِنَّ ٱلَّذِينَ يَرْمُونَ ٱلْمُحْصَنَـٰتِ ٱلْغَـٰفِلَـٰتِ ٱلْمُؤْمِنَـٰتِ لُعِنُوا۟ فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ وَلَهُمْ عَذَابٌ عَظِيمٌ","en":"Indeed, those who [falsely] accuse chaste, unaware and believing women are cursed in this world and the Hereafter; and they will have a great punishment","tr":"Inna allatheena yarmoona almuhsanatialghafilati almu/minati luAAinoo fee addunyawal-akhirati walahum AAathabun AAatheem","juz":18,"page":352},{"s":24,"a":24,"key":"24:24","ar":"يَوْمَ تَشْهَدُ عَلَيْهِمْ أَلْسِنَتُهُمْ وَأَيْدِيهِمْ وَأَرْجُلُهُم بِمَا كَانُوا۟ يَعْمَلُونَ","en":"On a Day when their tongues, their hands and their feet will bear witness against them as to what they used to do.","tr":"Yawma tashhadu AAalayhim alsinatuhumwaaydeehim waarjuluhum bima kanoo yaAAmaloon","juz":18,"page":352},{"s":24,"a":25,"key":"24:25","ar":"يَوْمَئِذٍ يُوَفِّيهِمُ ٱللَّهُ دِينَهُمُ ٱلْحَقَّ وَيَعْلَمُونَ أَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ ٱلْمُبِينُ","en":"That Day, Allāh will pay them in full their true [i.e., deserved] recompense, and they will know that it is Allāh who is the manifest Truth [i.e., perfect in justice].","tr":"Yawma-ithin yuwaffeehimu Allahudeenahumu alhaqqa wayaAAlamoona anna Allaha huwa alhaqqualmubeen","juz":18,"page":352},{"s":24,"a":26,"key":"24:26","ar":"ٱلْخَبِيثَـٰتُ لِلْخَبِيثِينَ وَٱلْخَبِيثُونَ لِلْخَبِيثَـٰتِ ۖ وَٱلطَّيِّبَـٰتُ لِلطَّيِّبِينَ وَٱلطَّيِّبُونَ لِلطَّيِّبَـٰتِ ۚ أُو۟لَـٰٓئِكَ مُبَرَّءُونَ مِمَّا يَقُولُونَ ۖ لَهُم مَّغْفِرَةٌ وَرِزْقٌ كَرِيمٌ","en":"Evil words are for evil men, and evil men are [subjected] to evil words. And good words are for good men, and good men are [an object] of good words.1 Those [good people] are declared innocent of what they [i.e., slanderers] say. For them is forgiveness and noble provision.","tr":"Alkhabeethatu lilkhabeetheena walkhabeethoonalilkhabeethati wattayyibatu littayyibeenawattayyiboona littayyibatiola-ika mubarraoona mimma yaqooloona lahummaghfiratun warizqun kareem","juz":18,"page":352},{"s":24,"a":27,"key":"24:27","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَدْخُلُوا۟ بُيُوتًا غَيْرَ بُيُوتِكُمْ حَتَّىٰ تَسْتَأْنِسُوا۟ وَتُسَلِّمُوا۟ عَلَىٰٓ أَهْلِهَا ۚ ذَٰلِكُمْ خَيْرٌ لَّكُمْ لَعَلَّكُمْ تَذَكَّرُونَ","en":"O you who have believed, do not enter houses other than your own houses until you ascertain welcome and greet1 their inhabitants. That is best for you; perhaps you will be reminded [i.e., advised].","tr":"Ya ayyuha allatheena amanoola tadkhuloo buyootan ghayra buyootikum hattatasta/nisoo watusallimoo AAala ahliha thalikumkhayrun lakum laAAallakum tathakkaroon","juz":18,"page":352},{"s":24,"a":28,"key":"24:28","ar":"فَإِن لَّمْ تَجِدُوا۟ فِيهَآ أَحَدًا فَلَا تَدْخُلُوهَا حَتَّىٰ يُؤْذَنَ لَكُمْ ۖ وَإِن قِيلَ لَكُمُ ٱرْجِعُوا۟ فَٱرْجِعُوا۟ ۖ هُوَ أَزْكَىٰ لَكُمْ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ عَلِيمٌ","en":"And if you do not find anyone therein, do not enter them until permission has been given you. And if it is said to you, \"Go back,\"1 then go back; it is purer for you. And Allāh is Knowing of what you do.","tr":"Fa-in lam tajidoo feeha ahadanfala tadkhulooha hatta yu/thanalakum wa-in qeela lakumu irjiAAoo farjiAAoo huwa azkalakum wallahu bima taAAmaloona AAaleem","juz":18,"page":353},{"s":24,"a":29,"key":"24:29","ar":"لَّيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَدْخُلُوا۟ بُيُوتًا غَيْرَ مَسْكُونَةٍ فِيهَا مَتَـٰعٌ لَّكُمْ ۚ وَٱللَّهُ يَعْلَمُ مَا تُبْدُونَ وَمَا تَكْتُمُونَ","en":"There is no blame upon you for entering houses not inhabited in which there is convenience1 for you. And Allāh knows what you reveal and what you conceal.","tr":"Laysa AAalaykum junahun an tadkhuloobuyootan ghayra maskoonatin feeha mataAAun lakum wallahuyaAAlamu ma tubdoona wama taktumoon","juz":18,"page":353},{"s":24,"a":30,"key":"24:30","ar":"قُل لِّلْمُؤْمِنِينَ يَغُضُّوا۟ مِنْ أَبْصَـٰرِهِمْ وَيَحْفَظُوا۟ فُرُوجَهُمْ ۚ ذَٰلِكَ أَزْكَىٰ لَهُمْ ۗ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا يَصْنَعُونَ","en":"Tell the believing men to reduce [some] of their vision1 and guard their private parts.2 That is purer for them. Indeed, Allāh is [fully] Aware of what they do.","tr":"Qul lilmu/mineena yaghuddoo min absarihumwayahfathoo furoojahum thalika azkalahum inna Allaha khabeerun bima yasnaAAoon","juz":18,"page":353},{"s":24,"a":31,"key":"24:31","ar":"وَقُل لِّلْمُؤْمِنَـٰتِ يَغْضُضْنَ مِنْ أَبْصَـٰرِهِنَّ وَيَحْفَظْنَ فُرُوجَهُنَّ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا مَا ظَهَرَ مِنْهَا ۖ وَلْيَضْرِبْنَ بِخُمُرِهِنَّ عَلَىٰ جُيُوبِهِنَّ ۖ وَلَا يُبْدِينَ زِينَتَهُنَّ إِلَّا لِبُعُولَتِهِنَّ أَوْ ءَابَآئِهِنَّ أَوْ ءَابَآءِ بُعُولَتِهِنَّ أَوْ أَبْنَآئِهِنَّ أَوْ أَبْنَآءِ بُعُولَتِهِنَّ أَوْ إِخْوَٰنِهِنَّ أَوْ بَنِىٓ إِخْوَٰنِهِنَّ أَوْ بَنِىٓ أَخَوَٰتِهِنَّ أَوْ نِسَآئِهِنَّ أَوْ مَا مَلَكَتْ أَيْمَـٰنُهُنَّ أَوِ ٱلتَّـٰبِعِينَ غَيْرِ أُو۟لِى ٱلْإِرْبَةِ مِنَ ٱلرِّجَالِ أَوِ ٱلطِّفْلِ ٱلَّذِينَ لَمْ يَظْهَرُوا۟ عَلَىٰ عَوْرَٰتِ ٱلنِّسَآءِ ۖ وَلَا يَضْرِبْنَ بِأَرْجُلِهِنَّ لِيُعْلَمَ مَا يُخْفِينَ مِن زِينَتِهِنَّ ۚ وَتُوبُوٓا۟ إِلَى ٱللَّهِ جَمِيعًا أَيُّهَ ٱلْمُؤْمِنُونَ لَعَلَّكُمْ تُفْلِحُونَ","en":"And tell the believing women to reduce [some] of their vision1 and guard their private parts and not expose their adornment2 except that which [necessarily] appears thereof3 and to wrap [a portion of] their headcovers over their chests and not expose their adornment [i.e., beauty] except to their husbands, their fathers, their husbands' fathers, their sons, their husbands' sons, their brothers, their brothers' sons, their sisters' sons, their women, that which their right hands possess [i.e., slaves], or those male attendants having no physical desire,4 or children who are not yet aware of the private aspects of women. And let them not stamp their feet to make known what they conceal of their adornment. And turn to Allāh in repentance, all of you, O believers, that you might succeed.","tr":"Waqul lilmu/minati yaghdudnamin absarihinna wayahfathnafuroojahunna wala yubdeena zeenatahunna illa mathahara minha walyadribnabikhumurihinna AAala juyoobihinna wala yubdeenazeenatahunna illa libuAAoolatihinna aw aba-ihinnaaw aba-i buAAoolatihinna aw abna-ihinna awabna-i buAAoolatihinna aw ikhwanihinna aw baneeikhwanihinna aw banee akhawatihinna aw nisa-ihinnaaw ma malakat aymanuhunna awi attabiAAeenaghayri olee al-irbati mina arrijali awi attifliallatheena lam yathharoo AAala AAawratiannisa-i wala yadribnabi-arjulihinna liyuAAlama ma yukhfeena min zeenatihinnawatooboo ila Allahi jameeAAan ayyuhaalmu/minoona laAAallakum tuflihoon","juz":18,"page":353},{"s":24,"a":32,"key":"24:32","ar":"وَأَنكِحُوا۟ ٱلْأَيَـٰمَىٰ مِنكُمْ وَٱلصَّـٰلِحِينَ مِنْ عِبَادِكُمْ وَإِمَآئِكُمْ ۚ إِن يَكُونُوا۟ فُقَرَآءَ يُغْنِهِمُ ٱللَّهُ مِن فَضْلِهِۦ ۗ وَٱللَّهُ وَٰسِعٌ عَلِيمٌ","en":"And marry the unmarried among you and the righteous among your male slaves and female slaves. If they should be poor, Allāh will enrich them from His bounty, and Allāh is all-Encompassing and Knowing.","tr":"Waankihoo al-ayamaminkum wassaliheena min AAibadikumwa-ima-ikum in yakoonoo fuqaraa yughnihimu Allahumin fadlihi wallahu wasiAAun AAaleem","juz":18,"page":354},{"s":24,"a":33,"key":"24:33","ar":"وَلْيَسْتَعْفِفِ ٱلَّذِينَ لَا يَجِدُونَ نِكَاحًا حَتَّىٰ يُغْنِيَهُمُ ٱللَّهُ مِن فَضْلِهِۦ ۗ وَٱلَّذِينَ يَبْتَغُونَ ٱلْكِتَـٰبَ مِمَّا مَلَكَتْ أَيْمَـٰنُكُمْ فَكَاتِبُوهُمْ إِنْ عَلِمْتُمْ فِيهِمْ خَيْرًا ۖ وَءَاتُوهُم مِّن مَّالِ ٱللَّهِ ٱلَّذِىٓ ءَاتَىٰكُمْ ۚ وَلَا تُكْرِهُوا۟ فَتَيَـٰتِكُمْ عَلَى ٱلْبِغَآءِ إِنْ أَرَدْنَ تَحَصُّنًا لِّتَبْتَغُوا۟ عَرَضَ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَمَن يُكْرِههُّنَّ فَإِنَّ ٱللَّهَ مِنۢ بَعْدِ إِكْرَٰهِهِنَّ غَفُورٌ رَّحِيمٌ","en":"But let them who find not [the means for] marriage abstain [from sexual relations] until Allāh enriches them from His bounty. And those who seek a contract [for eventual emancipation] from among whom your right hands possess1 - then make a contract with them if you know there is within them goodness and give them from the wealth of Allāh which He has given you. And do not compel your slave girls to prostitution, if they desire chastity, to seek [thereby] the temporary interests of worldly life. And if someone should compel them, then indeed, Allāh is [to them], after their compulsion, Forgiving and Merciful.","tr":"WalyastaAAfifi allatheena layajidoona nikahan hatta yughniyahumu Allahumin fadlihi wallatheena yabtaghoona alkitabamimma malakat aymanukum fakatiboohum inAAalimtum feehim khayran waatoohum min mali Allahiallathee atakum wala tukrihoo fatayatikumAAala albigha-i in aradna tahassunanlitabtaghoo AAarada alhayati addunyawaman yukrihhunna fa-inna Allaha min baAAdi ikrahihinnaghafoorun raheem","juz":18,"page":354},{"s":24,"a":34,"key":"24:34","ar":"وَلَقَدْ أَنزَلْنَآ إِلَيْكُمْ ءَايَـٰتٍ مُّبَيِّنَـٰتٍ وَمَثَلًا مِّنَ ٱلَّذِينَ خَلَوْا۟ مِن قَبْلِكُمْ وَمَوْعِظَةً لِّلْمُتَّقِينَ","en":"And We have certainly sent down to you distinct verses1 and examples from those who passed on before you and an admonition for those who fear Allāh.","tr":"Walaqad anzalna ilaykum ayatinmubayyinatin wamathalan mina allatheena khalaw minqablikum wamawAAithatan lilmuttaqeen","juz":18,"page":354},{"s":24,"a":35,"key":"24:35","ar":"۞ ٱللَّهُ نُورُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ مَثَلُ نُورِهِۦ كَمِشْكَوٰةٍ فِيهَا مِصْبَاحٌ ۖ ٱلْمِصْبَاحُ فِى زُجَاجَةٍ ۖ ٱلزُّجَاجَةُ كَأَنَّهَا كَوْكَبٌ دُرِّىٌّ يُوقَدُ مِن شَجَرَةٍ مُّبَـٰرَكَةٍ زَيْتُونَةٍ لَّا شَرْقِيَّةٍ وَلَا غَرْبِيَّةٍ يَكَادُ زَيْتُهَا يُضِىٓءُ وَلَوْ لَمْ تَمْسَسْهُ نَارٌ ۚ نُّورٌ عَلَىٰ نُورٍ ۗ يَهْدِى ٱللَّهُ لِنُورِهِۦ مَن يَشَآءُ ۚ وَيَضْرِبُ ٱللَّهُ ٱلْأَمْثَـٰلَ لِلنَّاسِ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"Allāh is the Light1 of the heavens and the earth. The example of His light2 is like a niche within which is a lamp;3 the lamp is within glass, the glass as if it were a pearly [white] star lit from [the oil of] a blessed olive tree, neither of the east nor of the west, whose oil would almost glow even if untouched by fire. Light upon light. Allāh guides to His light whom He wills. And Allāh presents examples for the people, and Allāh is Knowing of all things.","tr":"Allahu nooru assamawatiwal-ardi mathalu noorihi kamishkatin feehamisbahun almisbahu fee zujajatinazzujajatu kaannaha kawkabun durriyyunyooqadu min shajaratin mubarakatin zaytoonatin lasharqiyyatin wala gharbiyyatin yakadu zaytuhayudee-o walaw lam tamsas-hu narun noorun AAalanoorin yahdee Allahu linoorihi man yashao wayadribuAllahu al-amthala linnasi wallahubikulli shay-in AAaleem","juz":18,"page":354},{"s":24,"a":36,"key":"24:36","ar":"فِى بُيُوتٍ أَذِنَ ٱللَّهُ أَن تُرْفَعَ وَيُذْكَرَ فِيهَا ٱسْمُهُۥ يُسَبِّحُ لَهُۥ فِيهَا بِٱلْغُدُوِّ وَٱلْـَٔاصَالِ","en":"[Such niches are] in houses [i.e., mosques] which Allāh has ordered to be raised and that His name be mentioned [i.e., praised] therein; exalting Him within them in the morning and the evenings1","tr":"Fee buyootin athina Allahu anturfaAAa wayuthkara feeha ismuhu yusabbihulahu feeha bilghuduwwi wal-asal","juz":18,"page":354},{"s":24,"a":37,"key":"24:37","ar":"رِجَالٌ لَّا تُلْهِيهِمْ تِجَـٰرَةٌ وَلَا بَيْعٌ عَن ذِكْرِ ٱللَّهِ وَإِقَامِ ٱلصَّلَوٰةِ وَإِيتَآءِ ٱلزَّكَوٰةِ ۙ يَخَافُونَ يَوْمًا تَتَقَلَّبُ فِيهِ ٱلْقُلُوبُ وَٱلْأَبْصَـٰرُ","en":"[Are] men whom neither commerce nor sale distracts from the remembrance of Allāh and performance of prayer and giving of zakāh. They fear a Day in which the hearts and eyes will [fearfully] turn about -","tr":"Rijalun la tulheehim tijaratunwala bayAAun AAan thikri Allahi wa-iqamiassalati wa-eeta-i azzakatiyakhafoona yawman tataqallabu feehi alquloobu wal-absar","juz":18,"page":355},{"s":24,"a":38,"key":"24:38","ar":"لِيَجْزِيَهُمُ ٱللَّهُ أَحْسَنَ مَا عَمِلُوا۟ وَيَزِيدَهُم مِّن فَضْلِهِۦ ۗ وَٱللَّهُ يَرْزُقُ مَن يَشَآءُ بِغَيْرِ حِسَابٍ","en":"That Allāh may reward them [according to] the best of what they did and increase them from His bounty. And Allāh gives provision to whom He wills without account [i.e., limit].","tr":"Liyajziyahumu Allahu ahsana maAAamiloo wayazeedahum min fadlihi wallahuyarzuqu man yashao bighayri hisab","juz":18,"page":355},{"s":24,"a":39,"key":"24:39","ar":"وَٱلَّذِينَ كَفَرُوٓا۟ أَعْمَـٰلُهُمْ كَسَرَابٍۭ بِقِيعَةٍ يَحْسَبُهُ ٱلظَّمْـَٔانُ مَآءً حَتَّىٰٓ إِذَا جَآءَهُۥ لَمْ يَجِدْهُ شَيْـًٔا وَوَجَدَ ٱللَّهَ عِندَهُۥ فَوَفَّىٰهُ حِسَابَهُۥ ۗ وَٱللَّهُ سَرِيعُ ٱلْحِسَابِ","en":"But those who disbelieved - their deeds are like a mirage in a lowland which a thirsty one thinks is water until, when he comes to it, he finds it is nothing but finds Allāh before him, and He will pay him in full his due; and Allāh is swift in account.","tr":"Wallatheena kafaroo aAAmaluhumkasarabin biqeeAAatin yahsabuhu aththam-anumaan hatta itha jaahu lamyajidhu shay-an wawajada Allaha AAindahu fawaffahu hisabahuwallahu sareeAAu alhisab","juz":18,"page":355},{"s":24,"a":40,"key":"24:40","ar":"أَوْ كَظُلُمَـٰتٍ فِى بَحْرٍ لُّجِّىٍّ يَغْشَىٰهُ مَوْجٌ مِّن فَوْقِهِۦ مَوْجٌ مِّن فَوْقِهِۦ سَحَابٌ ۚ ظُلُمَـٰتٌۢ بَعْضُهَا فَوْقَ بَعْضٍ إِذَآ أَخْرَجَ يَدَهُۥ لَمْ يَكَدْ يَرَىٰهَا ۗ وَمَن لَّمْ يَجْعَلِ ٱللَّهُ لَهُۥ نُورًا فَمَا لَهُۥ مِن نُّورٍ","en":"Or [they are] like darknesses within an unfathomable sea which is covered by waves, upon which are waves, over which are clouds - darknesses, some of them upon others. When one puts out his hand [therein], he can hardly see it. And he to whom Allāh has not granted light - for him there is no light.","tr":"Aw kathulumatin fee bahrinlujjiyyin yaghshahu mawjun min fawqihi mawjun min fawqihisahabun thulumatun baAAduhafawqa baAAdin itha akhraja yadahu lam yakad yarahawaman lam yajAAali Allahu lahu nooran fama lahu minnoor","juz":18,"page":355},{"s":24,"a":41,"key":"24:41","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ يُسَبِّحُ لَهُۥ مَن فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَٱلطَّيْرُ صَـٰٓفَّـٰتٍ ۖ كُلٌّ قَدْ عَلِمَ صَلَاتَهُۥ وَتَسْبِيحَهُۥ ۗ وَٱللَّهُ عَلِيمٌۢ بِمَا يَفْعَلُونَ","en":"Do you not see that Allāh is exalted by whomever is within the heavens and the earth and [by] the birds with wings spread [in flight]? Each [of them] has known his [means of] prayer and exalting [Him], and Allāh is Knowing of what they do.","tr":"Alam tara anna Allaha yusabbihulahu man fee assamawati wal-ardiwattayru saffatin kullun qadAAalima salatahu watasbeehahu wallahuAAaleemun bima yafAAaloon","juz":18,"page":355},{"s":24,"a":42,"key":"24:42","ar":"وَلِلَّهِ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ وَإِلَى ٱللَّهِ ٱلْمَصِيرُ","en":"And to Allāh belongs the dominion of the heavens and the earth, and to Allāh is the destination.","tr":"Walillahi mulku assamawatiwal-ardi wa-ila Allahi almaseer","juz":18,"page":355},{"s":24,"a":43,"key":"24:43","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ يُزْجِى سَحَابًا ثُمَّ يُؤَلِّفُ بَيْنَهُۥ ثُمَّ يَجْعَلُهُۥ رُكَامًا فَتَرَى ٱلْوَدْقَ يَخْرُجُ مِنْ خِلَـٰلِهِۦ وَيُنَزِّلُ مِنَ ٱلسَّمَآءِ مِن جِبَالٍ فِيهَا مِنۢ بَرَدٍ فَيُصِيبُ بِهِۦ مَن يَشَآءُ وَيَصْرِفُهُۥ عَن مَّن يَشَآءُ ۖ يَكَادُ سَنَا بَرْقِهِۦ يَذْهَبُ بِٱلْأَبْصَـٰرِ","en":"Do you not see that Allāh drives clouds? Then He brings them together; then He makes them into a mass, and you see the rain emerge from within it. And He sends down from the sky, mountains [of clouds] within which is hail, and He strikes with it whom He wills and averts it from whom He wills. The flash of its lightning almost takes away the eyesight.","tr":"Alam tara anna Allaha yuzjee sahabanthumma yu-allifu baynahu thumma yajAAaluhu rukaman fataraalwadqa yakhruju min khilalihi wayunazzilu mina assama-imin jibalin feeha min baradin fayuseebu bihiman yashao wayasrifuhu AAan man yashao yakadusana barqihi yathhabu bil-absar","juz":18,"page":355},{"s":24,"a":44,"key":"24:44","ar":"يُقَلِّبُ ٱللَّهُ ٱلَّيْلَ وَٱلنَّهَارَ ۚ إِنَّ فِى ذَٰلِكَ لَعِبْرَةً لِّأُو۟لِى ٱلْأَبْصَـٰرِ","en":"Allāh alternates the night and the day. Indeed in that is a lesson for those who have vision.","tr":"Yuqallibu Allahu allayla wannaharainna fee thalika laAAibratan li-olee al-absar","juz":18,"page":356},{"s":24,"a":45,"key":"24:45","ar":"وَٱللَّهُ خَلَقَ كُلَّ دَآبَّةٍ مِّن مَّآءٍ ۖ فَمِنْهُم مَّن يَمْشِى عَلَىٰ بَطْنِهِۦ وَمِنْهُم مَّن يَمْشِى عَلَىٰ رِجْلَيْنِ وَمِنْهُم مَّن يَمْشِى عَلَىٰٓ أَرْبَعٍ ۚ يَخْلُقُ ٱللَّهُ مَا يَشَآءُ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Allāh has created every [living] creature from water. And of them are those that move on their bellies, and of them are those that walk on two legs, and of them are those that walk on four. Allāh creates what He wills. Indeed, Allāh is over all things competent.","tr":"Wallahu khalaqa kulla dabbatinmin ma-in faminhum man yamshee AAala batnihiwaminhum man yamshee AAala rijlayni waminhum man yamsheeAAala arbaAAin yakhluqu Allahu ma yashaoinna Allaha AAala kulli shay-in qadeer","juz":18,"page":356},{"s":24,"a":46,"key":"24:46","ar":"لَّقَدْ أَنزَلْنَآ ءَايَـٰتٍ مُّبَيِّنَـٰتٍ ۚ وَٱللَّهُ يَهْدِى مَن يَشَآءُ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"We have certainly sent down distinct verses. And Allāh guides whom He wills to a straight path.","tr":"Laqad anzalna ayatinmubayyinatin wallahu yahdee man yashaoila siratin mustaqeem","juz":18,"page":356},{"s":24,"a":47,"key":"24:47","ar":"وَيَقُولُونَ ءَامَنَّا بِٱللَّهِ وَبِٱلرَّسُولِ وَأَطَعْنَا ثُمَّ يَتَوَلَّىٰ فَرِيقٌ مِّنْهُم مِّنۢ بَعْدِ ذَٰلِكَ ۚ وَمَآ أُو۟لَـٰٓئِكَ بِٱلْمُؤْمِنِينَ","en":"But they [i.e., the hypocrites] say, \"We have believed in Allāh and in the Messenger, and we obey\"; then a party of them turns away after that. And those are not believers.","tr":"Wayaqooloona amanna billahiwabirrasooli waataAAna thumma yatawallafareequn minhum min baAAdi thalika wama ola-ikabilmu/mineen","juz":18,"page":356},{"s":24,"a":48,"key":"24:48","ar":"وَإِذَا دُعُوٓا۟ إِلَى ٱللَّهِ وَرَسُولِهِۦ لِيَحْكُمَ بَيْنَهُمْ إِذَا فَرِيقٌ مِّنْهُم مُّعْرِضُونَ","en":"And when they are called to [the words of] Allāh and His Messenger to judge between them, at once a party of them turns aside [in refusal].","tr":"Wa-itha duAAoo ila Allahiwarasoolihi liyahkuma baynahum itha fareequn minhummuAAridoon","juz":18,"page":356},{"s":24,"a":49,"key":"24:49","ar":"وَإِن يَكُن لَّهُمُ ٱلْحَقُّ يَأْتُوٓا۟ إِلَيْهِ مُذْعِنِينَ","en":"But if the right is theirs, they come to him in prompt obedience.","tr":"Wa-in yakun lahumu alhaqqu ya/tooilayhi muthAAineen","juz":18,"page":356},{"s":24,"a":50,"key":"24:50","ar":"أَفِى قُلُوبِهِم مَّرَضٌ أَمِ ٱرْتَابُوٓا۟ أَمْ يَخَافُونَ أَن يَحِيفَ ٱللَّهُ عَلَيْهِمْ وَرَسُولُهُۥ ۚ بَلْ أُو۟لَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ","en":"Is there disease in their hearts? Or have they doubted? Or do they fear that Allāh will be unjust to them, or His Messenger? Rather, it is they who are the wrongdoers [i.e., the unjust].","tr":"Afee quloobihim maradun ami irtabooam yakhafoona an yaheefa Allahu AAalayhimwarasooluhu bal ola-ika humu aththalimoon","juz":18,"page":356},{"s":24,"a":51,"key":"24:51","ar":"إِنَّمَا كَانَ قَوْلَ ٱلْمُؤْمِنِينَ إِذَا دُعُوٓا۟ إِلَى ٱللَّهِ وَرَسُولِهِۦ لِيَحْكُمَ بَيْنَهُمْ أَن يَقُولُوا۟ سَمِعْنَا وَأَطَعْنَا ۚ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"The only statement of the [true] believers when they are called to Allāh and His Messenger to judge between them is that they say, \"We hear and we obey.\" And those are the successful.","tr":"Innama kana qawla almu/mineenaitha duAAoo ila Allahi warasoolihi liyahkumabaynahum an yaqooloo samiAAna waataAAna waola-ikahumu almuflihoon","juz":18,"page":356},{"s":24,"a":52,"key":"24:52","ar":"وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ وَيَخْشَ ٱللَّهَ وَيَتَّقْهِ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْفَآئِزُونَ","en":"And whoever obeys Allāh and His Messenger and fears Allāh and is conscious of Him - it is those who are the attainers.","tr":"Waman yutiAAi Allahawarasoolahu wayakhsha Allaha wayattaqhi faola-ikahumu alfa-izoon","juz":18,"page":356},{"s":24,"a":53,"key":"24:53","ar":"۞ وَأَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَـٰنِهِمْ لَئِنْ أَمَرْتَهُمْ لَيَخْرُجُنَّ ۖ قُل لَّا تُقْسِمُوا۟ ۖ طَاعَةٌ مَّعْرُوفَةٌ ۚ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا تَعْمَلُونَ","en":"And they swear by Allāh their strongest oaths that if you ordered them, they would go forth [in Allāh's cause]. Say, \"Do not swear. [Such] obedience is known.1 Indeed, Allāh is [fully] Aware of that which you do.\"","tr":"Waaqsamoo billahi jahda aymanihimla-in amartahum layakhrujunna qul la tuqsimoo taAAatunmaAAroofatun inna Allaha khabeerun bima taAAmaloon","juz":18,"page":356},{"s":24,"a":54,"key":"24:54","ar":"قُلْ أَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ ۖ فَإِن تَوَلَّوْا۟ فَإِنَّمَا عَلَيْهِ مَا حُمِّلَ وَعَلَيْكُم مَّا حُمِّلْتُمْ ۖ وَإِن تُطِيعُوهُ تَهْتَدُوا۟ ۚ وَمَا عَلَى ٱلرَّسُولِ إِلَّا ٱلْبَلَـٰغُ ٱلْمُبِينُ","en":"Say, \"Obey Allāh and obey the Messenger; but if you turn away - then upon him is only that [duty] with which he has been charged, and upon you is that with which you have been charged. And if you obey him, you will be [rightly] guided. And there is not upon the Messenger except the [responsibility for] clear notification.\"","tr":"Qul ateeAAoo Allaha waateeAAooarrasoola fa-in tawallaw fa-innama AAalayhi mahummila waAAalaykum ma hummiltum wa-in tuteeAAoohutahtadoo wama AAala arrasooli illaalbalaghu almubeen","juz":18,"page":357},{"s":24,"a":55,"key":"24:55","ar":"وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ مِنكُمْ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَيَسْتَخْلِفَنَّهُمْ فِى ٱلْأَرْضِ كَمَا ٱسْتَخْلَفَ ٱلَّذِينَ مِن قَبْلِهِمْ وَلَيُمَكِّنَنَّ لَهُمْ دِينَهُمُ ٱلَّذِى ٱرْتَضَىٰ لَهُمْ وَلَيُبَدِّلَنَّهُم مِّنۢ بَعْدِ خَوْفِهِمْ أَمْنًا ۚ يَعْبُدُونَنِى لَا يُشْرِكُونَ بِى شَيْـًٔا ۚ وَمَن كَفَرَ بَعْدَ ذَٰلِكَ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ","en":"Allāh has promised those who have believed among you and done righteous deeds that He will surely grant them succession [to authority] upon the earth just as He granted it to those before them and that He will surely establish for them [therein] their religion which He has preferred for them and that He will surely substitute for them, after their fear, security, [for] they worship Me, not associating anything with Me. But whoever disbelieves1 after that - then those are the defiantly disobedient.","tr":"WaAAada Allahu allatheena amanoominkum waAAamiloo assalihatilayastakhlifannahum fee al-ardi kama istakhlafaallatheena min qablihim walayumakkinanna lahum deenahumuallathee irtada lahum walayubaddilannahum minbaAAdi khawfihim amnan yaAAbudoonanee la yushrikoona beeshay-an waman kafara baAAda thalika faola-ika humualfasiqoon","juz":18,"page":357},{"s":24,"a":56,"key":"24:56","ar":"وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَأَطِيعُوا۟ ٱلرَّسُولَ لَعَلَّكُمْ تُرْحَمُونَ","en":"And establish prayer and give zakāh and obey the Messenger - that you may receive mercy.","tr":"Waaqeemoo assalata waatooazzakata waateeAAoo arrasoolalaAAallakum turhamoon","juz":18,"page":357},{"s":24,"a":57,"key":"24:57","ar":"لَا تَحْسَبَنَّ ٱلَّذِينَ كَفَرُوا۟ مُعْجِزِينَ فِى ٱلْأَرْضِ ۚ وَمَأْوَىٰهُمُ ٱلنَّارُ ۖ وَلَبِئْسَ ٱلْمَصِيرُ","en":"Never think that the disbelievers are causing failure [to Allāh] upon the earth. Their refuge will be the Fire - and how wretched the destination.","tr":"La tahsabanna allatheenakafaroo muAAjizeena fee al-ardi wama/wahumu annaruwalabi/sa almaseer","juz":18,"page":357},{"s":24,"a":58,"key":"24:58","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لِيَسْتَـْٔذِنكُمُ ٱلَّذِينَ مَلَكَتْ أَيْمَـٰنُكُمْ وَٱلَّذِينَ لَمْ يَبْلُغُوا۟ ٱلْحُلُمَ مِنكُمْ ثَلَـٰثَ مَرَّٰتٍ ۚ مِّن قَبْلِ صَلَوٰةِ ٱلْفَجْرِ وَحِينَ تَضَعُونَ ثِيَابَكُم مِّنَ ٱلظَّهِيرَةِ وَمِنۢ بَعْدِ صَلَوٰةِ ٱلْعِشَآءِ ۚ ثَلَـٰثُ عَوْرَٰتٍ لَّكُمْ ۚ لَيْسَ عَلَيْكُمْ وَلَا عَلَيْهِمْ جُنَاحٌۢ بَعْدَهُنَّ ۚ طَوَّٰفُونَ عَلَيْكُم بَعْضُكُمْ عَلَىٰ بَعْضٍ ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْـَٔايَـٰتِ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"O you who have believed, let those whom your right hands possess and those who have not [yet] reached puberty among you ask permission of you [before entering] at three times: before the dawn prayer and when you put aside your clothing [for rest] at noon and after the night prayer. [These are] three times of privacy1 for you. There is no blame upon you nor upon them beyond these [periods], for they continually circulate among you - some of you, among others. Thus does Allāh make clear to you the verses [i.e., His ordinances]; and Allāh is Knowing and Wise.","tr":"Ya ayyuha allatheena amanooliyasta/thinkumu allatheena malakat aymanukumwallatheena lam yablughoo alhuluma minkumthalatha marratin min qabli salatialfajri waheena tadaAAoona thiyabakum mina aththaheeratiwamin baAAdi salati alAAisha-i thalathuAAawratin lakum laysa AAalaykum wala AAalayhim junahunbaAAdahunna tawwafoona AAalaykum baAAdukumAAala baAAdin kathalika yubayyinu Allahulakumu al-ayati wallahu AAaleemun hakeem","juz":18,"page":357},{"s":24,"a":59,"key":"24:59","ar":"وَإِذَا بَلَغَ ٱلْأَطْفَـٰلُ مِنكُمُ ٱلْحُلُمَ فَلْيَسْتَـْٔذِنُوا۟ كَمَا ٱسْتَـْٔذَنَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمْ ءَايَـٰتِهِۦ ۗ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"And when the children among you reach puberty, let them ask permission [at all times] as those before them have done. Thus does Allāh make clear to you His verses; and Allāh is Knowing and Wise.","tr":"Wa-itha balagha al-atfaluminkumu alhuluma falyasta/thinoo kama ista/thanaallatheena min qablihim kathalika yubayyinu Allahulakum ayatihi wallahu AAaleemun hakeem","juz":18,"page":358},{"s":24,"a":60,"key":"24:60","ar":"وَٱلْقَوَٰعِدُ مِنَ ٱلنِّسَآءِ ٱلَّـٰتِى لَا يَرْجُونَ نِكَاحًا فَلَيْسَ عَلَيْهِنَّ جُنَاحٌ أَن يَضَعْنَ ثِيَابَهُنَّ غَيْرَ مُتَبَرِّجَـٰتٍۭ بِزِينَةٍ ۖ وَأَن يَسْتَعْفِفْنَ خَيْرٌ لَّهُنَّ ۗ وَٱللَّهُ سَمِيعٌ عَلِيمٌ","en":"And women of post-menstrual age who have no desire for marriage - there is no blame upon them for putting aside their outer garments [but] not displaying adornment. But to modestly refrain [from that] is better for them. And Allāh is Hearing and Knowing.","tr":"WalqawaAAidu mina annisa-iallatee la yarjoona nikahan falaysaAAalayhinna junahun an yadaAAna thiyabahunnaghayra mutabarrijatin bizeenatin waan yastaAAfifna khayrunlahunna wallahu sameeAAun AAaleem","juz":18,"page":358},{"s":24,"a":61,"key":"24:61","ar":"لَّيْسَ عَلَى ٱلْأَعْمَىٰ حَرَجٌ وَلَا عَلَى ٱلْأَعْرَجِ حَرَجٌ وَلَا عَلَى ٱلْمَرِيضِ حَرَجٌ وَلَا عَلَىٰٓ أَنفُسِكُمْ أَن تَأْكُلُوا۟ مِنۢ بُيُوتِكُمْ أَوْ بُيُوتِ ءَابَآئِكُمْ أَوْ بُيُوتِ أُمَّهَـٰتِكُمْ أَوْ بُيُوتِ إِخْوَٰنِكُمْ أَوْ بُيُوتِ أَخَوَٰتِكُمْ أَوْ بُيُوتِ أَعْمَـٰمِكُمْ أَوْ بُيُوتِ عَمَّـٰتِكُمْ أَوْ بُيُوتِ أَخْوَٰلِكُمْ أَوْ بُيُوتِ خَـٰلَـٰتِكُمْ أَوْ مَا مَلَكْتُم مَّفَاتِحَهُۥٓ أَوْ صَدِيقِكُمْ ۚ لَيْسَ عَلَيْكُمْ جُنَاحٌ أَن تَأْكُلُوا۟ جَمِيعًا أَوْ أَشْتَاتًا ۚ فَإِذَا دَخَلْتُم بُيُوتًا فَسَلِّمُوا۟ عَلَىٰٓ أَنفُسِكُمْ تَحِيَّةً مِّنْ عِندِ ٱللَّهِ مُبَـٰرَكَةً طَيِّبَةً ۚ كَذَٰلِكَ يُبَيِّنُ ٱللَّهُ لَكُمُ ٱلْـَٔايَـٰتِ لَعَلَّكُمْ تَعْقِلُونَ","en":"There is not upon the blind [any] constraint nor upon the lame constraint nor upon the ill constraint nor upon yourselves when you eat from your [own] houses or the houses of your fathers or the houses of your mothers or the houses of your brothers or the houses of your sisters or the houses of your father's brothers or the houses of your father's sisters or the houses of your mother's brothers or the houses of your mother's sisters or [from houses] whose keys you possess or [from the house] of your friend. There is no blame upon you whether you eat together or separately. But when you enter houses, give greetings of peace1 upon each other - a greeting from Allāh, blessed and good. Thus does Allāh make clear to you the verses [of ordinance] that you may understand.","tr":"Laysa AAala al-aAAma harajunwala AAala al-aAAraji harajun walaAAala almareedi harajun wala AAalaanfusikum an ta/kuloo min buyootikum aw buyooti aba-ikumaw buyooti ommahatikum aw buyooti ikhwanikum awbuyooti akhawatikum aw buyooti aAAmamikum awbuyooti AAammatikum aw buyooti akhwalikum awbuyooti khalatikum aw ma malaktum mafatihahuaw sadeeqikum laysa AAalaykum junahun an ta/kuloojameeAAan aw ashtatan fa-itha dakhaltum buyootanfasallimoo AAala anfusikum tahiyyatan min AAindiAllahi mubarakatan tayyibatan kathalikayubayyinu Allahu lakumu al-ayati laAAallakumtaAAqiloon","juz":18,"page":358},{"s":24,"a":62,"key":"24:62","ar":"إِنَّمَا ٱلْمُؤْمِنُونَ ٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَإِذَا كَانُوا۟ مَعَهُۥ عَلَىٰٓ أَمْرٍ جَامِعٍ لَّمْ يَذْهَبُوا۟ حَتَّىٰ يَسْتَـْٔذِنُوهُ ۚ إِنَّ ٱلَّذِينَ يَسْتَـْٔذِنُونَكَ أُو۟لَـٰٓئِكَ ٱلَّذِينَ يُؤْمِنُونَ بِٱللَّهِ وَرَسُولِهِۦ ۚ فَإِذَا ٱسْتَـْٔذَنُوكَ لِبَعْضِ شَأْنِهِمْ فَأْذَن لِّمَن شِئْتَ مِنْهُمْ وَٱسْتَغْفِرْ لَهُمُ ٱللَّهَ ۚ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"The believers are only those who believe in Allāh and His Messenger and, when they are [meeting] with him for a matter of common interest, do not depart until they have asked his permission. Indeed, those who ask your permission, [O Muḥammad] - those are the ones who believe in Allāh and His Messenger. So when they ask your permission due to something of their affairs, then give permission to whom you will among them and ask forgiveness for them of Allāh. Indeed, Allāh is Forgiving and Merciful.","tr":"Innama almu/minoona allatheenaamanoo billahi warasoolihi wa-itha kanoomaAAahu AAala amrin jamiAAin lam yathhaboo hattayasta/thinoohu inna allatheena yasta/thinoonakaola-ika allatheena yu/minoona billahiwarasoolihi fa-itha ista/thanooka libaAAdisha/nihim fa/than liman shi/ta minhum wastaghfirlahumu Allaha inna Allaha ghafoorun raheem","juz":18,"page":359},{"s":24,"a":63,"key":"24:63","ar":"لَّا تَجْعَلُوا۟ دُعَآءَ ٱلرَّسُولِ بَيْنَكُمْ كَدُعَآءِ بَعْضِكُم بَعْضًا ۚ قَدْ يَعْلَمُ ٱللَّهُ ٱلَّذِينَ يَتَسَلَّلُونَ مِنكُمْ لِوَاذًا ۚ فَلْيَحْذَرِ ٱلَّذِينَ يُخَالِفُونَ عَنْ أَمْرِهِۦٓ أَن تُصِيبَهُمْ فِتْنَةٌ أَوْ يُصِيبَهُمْ عَذَابٌ أَلِيمٌ","en":"Do not make [your] calling of the Messenger among yourselves as the call of one of you to another. Already Allāh knows those of you who slip away, concealed by others. So let those beware who dissent from his [i.e., the Prophet's] order,1 lest fitnah2 strike them or a painful punishment.","tr":"La tajAAaloo duAAaa arrasoolibaynakum kaduAAa-i baAAdikum baAAdan qadyaAAlamu Allahu allatheena yatasallaloona minkumliwathan falyahthari allatheena yukhalifoonaAAan amrihi an tuseebahum fitnatun aw yuseebahumAAathabun aleem","juz":18,"page":359},{"s":24,"a":64,"key":"24:64","ar":"أَلَآ إِنَّ لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ قَدْ يَعْلَمُ مَآ أَنتُمْ عَلَيْهِ وَيَوْمَ يُرْجَعُونَ إِلَيْهِ فَيُنَبِّئُهُم بِمَا عَمِلُوا۟ ۗ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌۢ","en":"Unquestionably, to Allāh belongs whatever is in the heavens and earth. Already He knows that upon which you [stand]1 and [knows] the Day2 when they will be returned to Him and He will inform them of what they have done. And Allāh is Knowing of all things.","tr":"Ala inna lillahi ma feeassamawati wal-ardi qadyaAAlamu ma antum AAalayhi wayawma yurjaAAoona ilayhifayunabbi-ohum bima AAamiloo wallahubikulli shay-in AAaleem","juz":18,"page":359},{"s":25,"a":1,"key":"25:1","ar":" تَبَارَكَ ٱلَّذِى نَزَّلَ ٱلْفُرْقَانَ عَلَىٰ عَبْدِهِۦ لِيَكُونَ لِلْعَـٰلَمِينَ نَذِيرًا","en":"Blessed is He who sent down the Criterion upon His Servant that he may be to the worlds a warner -","tr":"Tabaraka allathee nazzalaalfurqana AAala AAabdihi liyakoona lilAAalameenanatheera","juz":18,"page":359},{"s":25,"a":2,"key":"25:2","ar":"ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَلَمْ يَتَّخِذْ وَلَدًا وَلَمْ يَكُن لَّهُۥ شَرِيكٌ فِى ٱلْمُلْكِ وَخَلَقَ كُلَّ شَىْءٍ فَقَدَّرَهُۥ تَقْدِيرًا","en":"He to whom belongs the dominion of the heavens and the earth and who has not taken a son and has not had a partner in dominion and has created each thing and determined it with [precise] determination.","tr":"Allathee lahu mulku assamawatiwal-ardi walam yattakhith waladan walamyakun lahu shareekun fee almulki wakhalaqa kulla shay-infaqaddarahu taqdeera","juz":18,"page":359},{"s":25,"a":3,"key":"25:3","ar":"وَٱتَّخَذُوا۟ مِن دُونِهِۦٓ ءَالِهَةً لَّا يَخْلُقُونَ شَيْـًٔا وَهُمْ يُخْلَقُونَ وَلَا يَمْلِكُونَ لِأَنفُسِهِمْ ضَرًّا وَلَا نَفْعًا وَلَا يَمْلِكُونَ مَوْتًا وَلَا حَيَوٰةً وَلَا نُشُورًا","en":"But they have taken besides Him gods which create nothing, while they are created, and possess not for themselves any harm or benefit and possess not [power to cause] death or life or resurrection.","tr":"Wattakhathoo min doonihi alihatanla yakhluqoona shay-an wahum yukhlaqoona walayamlikoona li-anfusihim darran wala nafAAan walayamlikoona mawtan wala hayatan walanushoora","juz":18,"page":360},{"s":25,"a":4,"key":"25:4","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ هَـٰذَآ إِلَّآ إِفْكٌ ٱفْتَرَىٰهُ وَأَعَانَهُۥ عَلَيْهِ قَوْمٌ ءَاخَرُونَ ۖ فَقَدْ جَآءُو ظُلْمًا وَزُورًا","en":"And those who disbelieve say, \"This [Qur’ān] is not except a falsehood he invented, and another people assisted him in it.\" But they have committed an injustice and a lie.","tr":"Waqala allatheena kafaroo in hathailla ifkun iftarahu waaAAanahu AAalayhiqawmun akharoona faqad jaoo thulmanwazoora","juz":18,"page":360},{"s":25,"a":5,"key":"25:5","ar":"وَقَالُوٓا۟ أَسَـٰطِيرُ ٱلْأَوَّلِينَ ٱكْتَتَبَهَا فَهِىَ تُمْلَىٰ عَلَيْهِ بُكْرَةً وَأَصِيلًا","en":"And they say, \"Legends of the former peoples which he has written down, and they are dictated to him morning and afternoon.\"","tr":"Waqaloo asateeru al-awwaleenaiktatabaha fahiya tumla AAalayhi bukratan waaseela","juz":18,"page":360},{"s":25,"a":6,"key":"25:6","ar":"قُلْ أَنزَلَهُ ٱلَّذِى يَعْلَمُ ٱلسِّرَّ فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ إِنَّهُۥ كَانَ غَفُورًا رَّحِيمًا","en":"Say, [O Muḥammad], \"It has been revealed by He who knows [every] secret within the heavens and the earth. Indeed, He is ever Forgiving and Merciful.\"","tr":"Qul anzalahu allathee yaAAlamu assirrafee assamawati wal-ardiinnahu kana ghafooran raheema","juz":18,"page":360},{"s":25,"a":7,"key":"25:7","ar":"وَقَالُوا۟ مَالِ هَـٰذَا ٱلرَّسُولِ يَأْكُلُ ٱلطَّعَامَ وَيَمْشِى فِى ٱلْأَسْوَاقِ ۙ لَوْلَآ أُنزِلَ إِلَيْهِ مَلَكٌ فَيَكُونَ مَعَهُۥ نَذِيرًا","en":"And they say, \"What is this messenger that eats food and walks in the markets? Why was there not sent down to him an angel so he would be with him a warner?","tr":"Waqaloo mali hatha arrasooliya/kulu attaAAama wayamshee fee al-aswaqilawla onzila ilayhi malakun fayakoona maAAahu natheera","juz":18,"page":360},{"s":25,"a":8,"key":"25:8","ar":"أَوْ يُلْقَىٰٓ إِلَيْهِ كَنزٌ أَوْ تَكُونُ لَهُۥ جَنَّةٌ يَأْكُلُ مِنْهَا ۚ وَقَالَ ٱلظَّـٰلِمُونَ إِن تَتَّبِعُونَ إِلَّا رَجُلًا مَّسْحُورًا","en":"Or [why is not] a treasure presented to him [from heaven], or does he [not] have a garden from which he eats?\" And the wrongdoers say, \"You follow not but a man affected by magic.\"","tr":"Aw yulqa ilayhi kanzun aw takoonu lahujannatun ya/kulu minha waqala aththalimoonain tattabiAAoona illa rajulan mashoora","juz":18,"page":360},{"s":25,"a":9,"key":"25:9","ar":"ٱنظُرْ كَيْفَ ضَرَبُوا۟ لَكَ ٱلْأَمْثَـٰلَ فَضَلُّوا۟ فَلَا يَسْتَطِيعُونَ سَبِيلًا","en":"Look how they strike for you comparisons;1 but they have strayed, so they cannot [find] a way.","tr":"Onthur kayfa daraboolaka al-amthala fadalloo fala yastateeAAoonasabeela","juz":18,"page":360},{"s":25,"a":10,"key":"25:10","ar":"تَبَارَكَ ٱلَّذِىٓ إِن شَآءَ جَعَلَ لَكَ خَيْرًا مِّن ذَٰلِكَ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ وَيَجْعَل لَّكَ قُصُورًۢا","en":"Blessed is He who, if He willed, could have made for you [something] better than that - gardens beneath which rivers flow - and could make for you palaces.","tr":"Tabaraka allathee in shaajaAAala laka khayran min thalika jannatin tajreemin tahtiha al-anharu wayajAAal laka qusoora","juz":18,"page":360},{"s":25,"a":11,"key":"25:11","ar":"بَلْ كَذَّبُوا۟ بِٱلسَّاعَةِ ۖ وَأَعْتَدْنَا لِمَن كَذَّبَ بِٱلسَّاعَةِ سَعِيرًا","en":"But they have denied the Hour, and We have prepared for those who deny the Hour a Blaze.","tr":"Bal kaththaboo bissaAAatiwaaAAtadna liman kaththaba bissaAAatisaAAeera","juz":18,"page":360},{"s":25,"a":12,"key":"25:12","ar":"إِذَا رَأَتْهُم مِّن مَّكَانٍۭ بَعِيدٍ سَمِعُوا۟ لَهَا تَغَيُّظًا وَزَفِيرًا","en":"When it [i.e., the Hellfire] sees them from a distant place, they will hear its fury and roaring.","tr":"Itha raat-hum min makaninbaAAeedin samiAAoo laha taghayyuthanwazafeera","juz":18,"page":361},{"s":25,"a":13,"key":"25:13","ar":"وَإِذَآ أُلْقُوا۟ مِنْهَا مَكَانًا ضَيِّقًا مُّقَرَّنِينَ دَعَوْا۟ هُنَالِكَ ثُبُورًا","en":"And when they are thrown into a narrow place therein bound in chains, they will cry out thereupon for destruction.","tr":"Wa-itha olqoo minha makanandayyiqan muqarraneena daAAaw hunalika thuboora","juz":18,"page":361},{"s":25,"a":14,"key":"25:14","ar":"لَّا تَدْعُوا۟ ٱلْيَوْمَ ثُبُورًا وَٰحِدًا وَٱدْعُوا۟ ثُبُورًا كَثِيرًا","en":"[They will be told], \"Do not cry this Day for one destruction but cry for much destruction.\"","tr":"La tadAAoo alyawma thubooran wahidanwadAAoo thubooran katheera","juz":18,"page":361},{"s":25,"a":15,"key":"25:15","ar":"قُلْ أَذَٰلِكَ خَيْرٌ أَمْ جَنَّةُ ٱلْخُلْدِ ٱلَّتِى وُعِدَ ٱلْمُتَّقُونَ ۚ كَانَتْ لَهُمْ جَزَآءً وَمَصِيرًا","en":"Say, \"Is that better or the Garden of Eternity which is promised to the righteous? It will be for them a reward and destination.","tr":"Qul athalika khayrun am jannatualkhuldi allatee wuAAida almuttaqoona kanat lahum jazaanwamaseera","juz":18,"page":361},{"s":25,"a":16,"key":"25:16","ar":"لَّهُمْ فِيهَا مَا يَشَآءُونَ خَـٰلِدِينَ ۚ كَانَ عَلَىٰ رَبِّكَ وَعْدًا مَّسْـُٔولًا","en":"For them therein is whatever they wish, [while] abiding eternally. It is ever upon your Lord a promise [worthy to be] requested.1","tr":"Lahum feeha ma yashaoonakhalideena kana AAala rabbika waAAdanmas-oola","juz":18,"page":361},{"s":25,"a":17,"key":"25:17","ar":"وَيَوْمَ يَحْشُرُهُمْ وَمَا يَعْبُدُونَ مِن دُونِ ٱللَّهِ فَيَقُولُ ءَأَنتُمْ أَضْلَلْتُمْ عِبَادِى هَـٰٓؤُلَآءِ أَمْ هُمْ ضَلُّوا۟ ٱلسَّبِيلَ","en":"And [mention] the Day He will gather them and that which they worship besides Allāh and will say, \"Did you mislead these, My servants, or did they [themselves] stray from the way?\"","tr":"Wayawma yahshuruhum wamayaAAbudoona min dooni Allahi fayaqoolu aantum adlaltumAAibadee haola-i am hum dalloo assabeel","juz":18,"page":361},{"s":25,"a":18,"key":"25:18","ar":"قَالُوا۟ سُبْحَـٰنَكَ مَا كَانَ يَنۢبَغِى لَنَآ أَن نَّتَّخِذَ مِن دُونِكَ مِنْ أَوْلِيَآءَ وَلَـٰكِن مَّتَّعْتَهُمْ وَءَابَآءَهُمْ حَتَّىٰ نَسُوا۟ ٱلذِّكْرَ وَكَانُوا۟ قَوْمًۢا بُورًا","en":"They will say, \"Exalted are You! It was not for us to take besides You any allies [i.e., protectors]. But You provided comforts for them and their fathers until they forgot the message and became a people ruined.\"","tr":"Qaloo subhanaka ma kanayanbaghee lana an nattakhitha min doonika min awliyaawalakin mattaAAtahum waabaahum hattanasoo aththikra wakanoo qawman boora","juz":18,"page":361},{"s":25,"a":19,"key":"25:19","ar":"فَقَدْ كَذَّبُوكُم بِمَا تَقُولُونَ فَمَا تَسْتَطِيعُونَ صَرْفًا وَلَا نَصْرًا ۚ وَمَن يَظْلِم مِّنكُمْ نُذِقْهُ عَذَابًا كَبِيرًا","en":"So they will deny you, [disbelievers], in what you say,1 and you cannot avert [punishment] or [find] help. And whoever commits injustice2 among you - We will make him taste a great punishment.","tr":"Faqad kaththabookum bimataqooloona fama tastateeAAoona sarfan walanasran waman yathlim minkum nuthiqhuAAathaban kabeera","juz":18,"page":361},{"s":25,"a":20,"key":"25:20","ar":"وَمَآ أَرْسَلْنَا قَبْلَكَ مِنَ ٱلْمُرْسَلِينَ إِلَّآ إِنَّهُمْ لَيَأْكُلُونَ ٱلطَّعَامَ وَيَمْشُونَ فِى ٱلْأَسْوَاقِ ۗ وَجَعَلْنَا بَعْضَكُمْ لِبَعْضٍ فِتْنَةً أَتَصْبِرُونَ ۗ وَكَانَ رَبُّكَ بَصِيرًا","en":"And We did not send before you, [O Muḥammad], any of the messengers except that they ate food and walked in the markets. And We have made some of you [people] as trial for others - will you have patience? And ever is your Lord, Seeing.","tr":"Wama arsalna qablaka minaalmursaleena illa innahum laya/kuloona attaAAamawayamshoona fee al-aswaqi wajaAAalna baAAdakumlibaAAdin fitnatan atasbiroona wakanarabbuka baseera","juz":18,"page":361},{"s":25,"a":21,"key":"25:21","ar":"۞ وَقَالَ ٱلَّذِينَ لَا يَرْجُونَ لِقَآءَنَا لَوْلَآ أُنزِلَ عَلَيْنَا ٱلْمَلَـٰٓئِكَةُ أَوْ نَرَىٰ رَبَّنَا ۗ لَقَدِ ٱسْتَكْبَرُوا۟ فِىٓ أَنفُسِهِمْ وَعَتَوْ عُتُوًّا كَبِيرًا","en":"And those who do not expect the meeting with Us say, \"Why were not angels sent down to us, or [why] do we [not] see our Lord?\" They have certainly become arrogant within themselves1 and [become] insolent with great insolence.","tr":"Waqala allatheena layarjoona liqaana lawla onzila AAalaynaalmala-ikatu aw nara rabbana laqadiistakbaroo fee anfusihim waAAataw AAutuwwan kabeera","juz":19,"page":362},{"s":25,"a":22,"key":"25:22","ar":"يَوْمَ يَرَوْنَ ٱلْمَلَـٰٓئِكَةَ لَا بُشْرَىٰ يَوْمَئِذٍ لِّلْمُجْرِمِينَ وَيَقُولُونَ حِجْرًا مَّحْجُورًا","en":"The day they see the angels1 - no good tidings will there be that day for the criminals, and [the angels] will say, \"Prevented and inaccessible.\"2","tr":"Yawma yarawna almala-ikata labushra yawma-ithin lilmujrimeena wayaqooloona hijranmahjoora","juz":19,"page":362},{"s":25,"a":23,"key":"25:23","ar":"وَقَدِمْنَآ إِلَىٰ مَا عَمِلُوا۟ مِنْ عَمَلٍ فَجَعَلْنَـٰهُ هَبَآءً مَّنثُورًا","en":"And We will approach [i.e., regard]1 what they have done of deeds and make them as dust dispersed.","tr":"Waqadimna ila maAAamiloo min AAamalin fajaAAalnahu habaan manthoora","juz":19,"page":362},{"s":25,"a":24,"key":"25:24","ar":"أَصْحَـٰبُ ٱلْجَنَّةِ يَوْمَئِذٍ خَيْرٌ مُّسْتَقَرًّا وَأَحْسَنُ مَقِيلًا","en":"The companions of Paradise, that Day, are [in] a better settlement and better resting place.","tr":"As-habu aljannati yawma-ithinkhayrun mustaqarran waahsanu maqeela","juz":19,"page":362},{"s":25,"a":25,"key":"25:25","ar":"وَيَوْمَ تَشَقَّقُ ٱلسَّمَآءُ بِٱلْغَمَـٰمِ وَنُزِّلَ ٱلْمَلَـٰٓئِكَةُ تَنزِيلًا","en":"And [mention] the Day when the heaven will split open with [emerging] clouds,1 and the angels will be sent down in successive descent.","tr":"Wayawma tashaqqaqu assamao bilghamamiwanuzzila almala-ikatu tanzeela","juz":19,"page":362},{"s":25,"a":26,"key":"25:26","ar":"ٱلْمُلْكُ يَوْمَئِذٍ ٱلْحَقُّ لِلرَّحْمَـٰنِ ۚ وَكَانَ يَوْمًا عَلَى ٱلْكَـٰفِرِينَ عَسِيرًا","en":"True sovereignty, that Day, is for the Most Merciful. And it will be upon the disbelievers a difficult Day.","tr":"Almulku yawma-ithin alhaqqu lirrahmaniwakana yawman AAala alkafireena AAaseera","juz":19,"page":362},{"s":25,"a":27,"key":"25:27","ar":"وَيَوْمَ يَعَضُّ ٱلظَّالِمُ عَلَىٰ يَدَيْهِ يَقُولُ يَـٰلَيْتَنِى ٱتَّخَذْتُ مَعَ ٱلرَّسُولِ سَبِيلًا","en":"And the Day the wrongdoer will bite on his hands [in regret] he will say, \"Oh, I wish I had taken with the Messenger a way.1","tr":"Wayawma yaAAaddu aththalimuAAala yadayhi yaqoolu ya laytanee ittakhathtumaAAa arrasooli sabeela","juz":19,"page":362},{"s":25,"a":28,"key":"25:28","ar":"يَـٰوَيْلَتَىٰ لَيْتَنِى لَمْ أَتَّخِذْ فُلَانًا خَلِيلًا","en":"Oh, woe to me! I wish I had not taken that one1 as a friend.","tr":"Ya waylata laytanee lamattakhith fulanan khaleela","juz":19,"page":362},{"s":25,"a":29,"key":"25:29","ar":"لَّقَدْ أَضَلَّنِى عَنِ ٱلذِّكْرِ بَعْدَ إِذْ جَآءَنِى ۗ وَكَانَ ٱلشَّيْطَـٰنُ لِلْإِنسَـٰنِ خَذُولًا","en":"He led me away from the remembrance1 after it had come to me. And ever is Satan, to man, a deserter.\"2","tr":"Laqad adallanee AAani aththikribaAAda ith jaanee wakana ashshaytanulil-insani khathoola","juz":19,"page":362},{"s":25,"a":30,"key":"25:30","ar":"وَقَالَ ٱلرَّسُولُ يَـٰرَبِّ إِنَّ قَوْمِى ٱتَّخَذُوا۟ هَـٰذَا ٱلْقُرْءَانَ مَهْجُورًا","en":"And the Messenger has said, \"O my Lord, indeed my people have taken this Qur’ān as [a thing] abandoned.\"1","tr":"Waqala arrasoolu yarabbi inna qawmee ittakhathoo hatha alqur-anamahjoora","juz":19,"page":362},{"s":25,"a":31,"key":"25:31","ar":"وَكَذَٰلِكَ جَعَلْنَا لِكُلِّ نَبِىٍّ عَدُوًّا مِّنَ ٱلْمُجْرِمِينَ ۗ وَكَفَىٰ بِرَبِّكَ هَادِيًا وَنَصِيرًا","en":"And thus have We made for every prophet an enemy from among the criminals. But sufficient is your Lord as a guide and a helper.","tr":"Wakathalika jaAAalna likullinabiyyin AAaduwwan mina almujrimeena wakafa birabbika hadiyanwanaseera","juz":19,"page":362},{"s":25,"a":32,"key":"25:32","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَوْلَا نُزِّلَ عَلَيْهِ ٱلْقُرْءَانُ جُمْلَةً وَٰحِدَةً ۚ كَذَٰلِكَ لِنُثَبِّتَ بِهِۦ فُؤَادَكَ ۖ وَرَتَّلْنَـٰهُ تَرْتِيلًا","en":"And those who disbelieve say, \"Why was the Qur’ān not revealed to him all at once?\" Thus [it is] that We may strengthen thereby your heart. And We have spaced it distinctly.1","tr":"Waqala allatheena kafaroo lawlanuzzila AAalayhi alqur-anu jumlatan wahidatan kathalikalinuthabbita bihi fu-adaka warattalnahu tarteela","juz":19,"page":362},{"s":25,"a":33,"key":"25:33","ar":"وَلَا يَأْتُونَكَ بِمَثَلٍ إِلَّا جِئْنَـٰكَ بِٱلْحَقِّ وَأَحْسَنَ تَفْسِيرًا","en":"And they do not come to you with an example [i.e., argument] except that We bring you the truth and the best explanation.","tr":"Wala ya/toonaka bimathalin illaji/naka bilhaqqi waahsana tafseera","juz":19,"page":363},{"s":25,"a":34,"key":"25:34","ar":"ٱلَّذِينَ يُحْشَرُونَ عَلَىٰ وُجُوهِهِمْ إِلَىٰ جَهَنَّمَ أُو۟لَـٰٓئِكَ شَرٌّ مَّكَانًا وَأَضَلُّ سَبِيلًا","en":"The ones who are gathered on their faces to Hell - those are the worst in position and farthest astray in [their] way.","tr":"Allatheena yuhsharoona AAalawujoohihim ila jahannama ola-ika sharrun makananwaadallu sabeela","juz":19,"page":363},{"s":25,"a":35,"key":"25:35","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ وَجَعَلْنَا مَعَهُۥٓ أَخَاهُ هَـٰرُونَ وَزِيرًا","en":"And We had certainly given Moses the Scripture and appointed with him his brother Aaron as an assistant.","tr":"Walaqad atayna moosaalkitaba wajaAAalna maAAahu akhahu haroonawazeera","juz":19,"page":363},{"s":25,"a":36,"key":"25:36","ar":"فَقُلْنَا ٱذْهَبَآ إِلَى ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِنَا فَدَمَّرْنَـٰهُمْ تَدْمِيرًا","en":"And We said, \"Go both of you to the people who have denied Our signs.\" Then We destroyed them with [complete] destruction.","tr":"Faqulna ithhaba ilaalqawmi allatheena kaththaboo bi-ayatinafadammarnahum tadmeera","juz":19,"page":363},{"s":25,"a":37,"key":"25:37","ar":"وَقَوْمَ نُوحٍ لَّمَّا كَذَّبُوا۟ ٱلرُّسُلَ أَغْرَقْنَـٰهُمْ وَجَعَلْنَـٰهُمْ لِلنَّاسِ ءَايَةً ۖ وَأَعْتَدْنَا لِلظَّـٰلِمِينَ عَذَابًا أَلِيمًا","en":"And the people of Noah - when they denied the messengers,1 We drowned them, and We made them for mankind a sign. And We have prepared for the wrongdoers a painful punishment.","tr":"Waqawma noohin lamma kaththabooarrusula aghraqnahum wajaAAalnahum linnasiayatan waaAAtadna liththalimeenaAAathaban aleema","juz":19,"page":363},{"s":25,"a":38,"key":"25:38","ar":"وَعَادًا وَثَمُودَا۟ وَأَصْحَـٰبَ ٱلرَّسِّ وَقُرُونًۢا بَيْنَ ذَٰلِكَ كَثِيرًا","en":"And [We destroyed] ʿAad and Thamūd and the companions of the well1 and many generations between them.","tr":"WaAAadan wathamooda waas-habaarrassi waquroonan bayna thalika katheera","juz":19,"page":363},{"s":25,"a":39,"key":"25:39","ar":"وَكُلًّا ضَرَبْنَا لَهُ ٱلْأَمْثَـٰلَ ۖ وَكُلًّا تَبَّرْنَا تَتْبِيرًا","en":"And for each We presented examples [as warnings], and each We destroyed with [total] destruction.","tr":"Wakullan darabna lahu al-amthalawakullan tabbarna tatbeera","juz":19,"page":363},{"s":25,"a":40,"key":"25:40","ar":"وَلَقَدْ أَتَوْا۟ عَلَى ٱلْقَرْيَةِ ٱلَّتِىٓ أُمْطِرَتْ مَطَرَ ٱلسَّوْءِ ۚ أَفَلَمْ يَكُونُوا۟ يَرَوْنَهَا ۚ بَلْ كَانُوا۟ لَا يَرْجُونَ نُشُورًا","en":"And they have already come upon the town which was showered with a rain of evil [i.e., stones]. So have they not seen it? But they are not expecting resurrection.1","tr":"Walaqad ataw AAala alqaryati allateeomtirat matara assaw-i afalam yakoonooyarawnaha bal kanoo la yarjoona nushoora","juz":19,"page":363},{"s":25,"a":41,"key":"25:41","ar":"وَإِذَا رَأَوْكَ إِن يَتَّخِذُونَكَ إِلَّا هُزُوًا أَهَـٰذَا ٱلَّذِى بَعَثَ ٱللَّهُ رَسُولًا","en":"And when they see you, [O Muḥammad], they take you not except in ridicule, [saying], \"Is this the one whom Allāh has sent as a messenger?","tr":"Wa-itha raawka in yattakhithoonakailla huzuwan ahatha allathee baAAatha Allahurasoola","juz":19,"page":363},{"s":25,"a":42,"key":"25:42","ar":"إِن كَادَ لَيُضِلُّنَا عَنْ ءَالِهَتِنَا لَوْلَآ أَن صَبَرْنَا عَلَيْهَا ۚ وَسَوْفَ يَعْلَمُونَ حِينَ يَرَوْنَ ٱلْعَذَابَ مَنْ أَضَلُّ سَبِيلًا","en":"He almost would have misled us from our gods had we not been steadfast in [worship of] them.\" But they are going to know, when they see the punishment, who is farthest astray in [his] way.","tr":"In kada layudillunaAAan alihatina lawla an sabarnaAAalayha wasawfa yaAAlamoona heena yarawna alAAathabaman adallu sabeela","juz":19,"page":363},{"s":25,"a":43,"key":"25:43","ar":"أَرَءَيْتَ مَنِ ٱتَّخَذَ إِلَـٰهَهُۥ هَوَىٰهُ أَفَأَنتَ تَكُونُ عَلَيْهِ وَكِيلًا","en":"Have you seen the one who takes as his god his own desire? Then would you be responsible for him?","tr":"Araayta mani ittakhatha ilahahuhawahu afaanta takoonu AAalayhi wakeela","juz":19,"page":363},{"s":25,"a":44,"key":"25:44","ar":"أَمْ تَحْسَبُ أَنَّ أَكْثَرَهُمْ يَسْمَعُونَ أَوْ يَعْقِلُونَ ۚ إِنْ هُمْ إِلَّا كَٱلْأَنْعَـٰمِ ۖ بَلْ هُمْ أَضَلُّ سَبِيلًا","en":"Or do you think that most of them hear or reason? They are not except like livestock.1 Rather, they are [even] more astray in [their] way.","tr":"Am tahsabu anna aktharahumyasmaAAoona aw yaAAqiloona in hum illa kal-anAAamibal hum adallu sabeela","juz":19,"page":364},{"s":25,"a":45,"key":"25:45","ar":"أَلَمْ تَرَ إِلَىٰ رَبِّكَ كَيْفَ مَدَّ ٱلظِّلَّ وَلَوْ شَآءَ لَجَعَلَهُۥ سَاكِنًا ثُمَّ جَعَلْنَا ٱلشَّمْسَ عَلَيْهِ دَلِيلًا","en":"Have you not considered your Lord - how He extends the shadow, and if He willed, He could have made it stationary? Then We made the sun for it an indication.1","tr":"Alam tara ila rabbika kayfa madda aththillawalaw shaa lajaAAalahu sakinan thumma jaAAalnaashshamsa AAalayhi daleela","juz":19,"page":364},{"s":25,"a":46,"key":"25:46","ar":"ثُمَّ قَبَضْنَـٰهُ إِلَيْنَا قَبْضًا يَسِيرًا","en":"Then We [retract and] hold it with Us for a brief grasp.1","tr":"Thumma qabadnahu ilaynaqabdan yaseera","juz":19,"page":364},{"s":25,"a":47,"key":"25:47","ar":"وَهُوَ ٱلَّذِى جَعَلَ لَكُمُ ٱلَّيْلَ لِبَاسًا وَٱلنَّوْمَ سُبَاتًا وَجَعَلَ ٱلنَّهَارَ نُشُورًا","en":"And it is He who has made the night for you as clothing1 and sleep [a means for] rest and has made the day a resurrection.2","tr":"Wahuwa allathee jaAAala lakumuallayla libasan wannawma subatan wajaAAalaannahara nushoora","juz":19,"page":364},{"s":25,"a":48,"key":"25:48","ar":"وَهُوَ ٱلَّذِىٓ أَرْسَلَ ٱلرِّيَـٰحَ بُشْرًۢا بَيْنَ يَدَىْ رَحْمَتِهِۦ ۚ وَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءً طَهُورًا","en":"And it is He who sends the winds as good tidings before His mercy [i.e., rainfall], and We send down from the sky pure water","tr":"Wahuwa allathee arsala arriyahabushran bayna yaday rahmatihi waanzalna mina assama-imaan tahoora","juz":19,"page":364},{"s":25,"a":49,"key":"25:49","ar":"لِّنُحْـِۧىَ بِهِۦ بَلْدَةً مَّيْتًا وَنُسْقِيَهُۥ مِمَّا خَلَقْنَآ أَنْعَـٰمًا وَأَنَاسِىَّ كَثِيرًا","en":"That We may bring to life thereby a dead land and give it as drink to those We created of numerous livestock and men.","tr":"Linuhyiya bihi baldatan maytanwanusqiyahu mimma khalaqna anAAaman waanasiyyakatheera","juz":19,"page":364},{"s":25,"a":50,"key":"25:50","ar":"وَلَقَدْ صَرَّفْنَـٰهُ بَيْنَهُمْ لِيَذَّكَّرُوا۟ فَأَبَىٰٓ أَكْثَرُ ٱلنَّاسِ إِلَّا كُفُورًا","en":"And We have certainly distributed it among them that they might be reminded,1 but most of the people refuse except disbelief.","tr":"Walaqad sarrafnahu baynahumliyaththakkaroo faaba aktharu annasiilla kufoora","juz":19,"page":364},{"s":25,"a":51,"key":"25:51","ar":"وَلَوْ شِئْنَا لَبَعَثْنَا فِى كُلِّ قَرْيَةٍ نَّذِيرًا","en":"And if We had willed, We could have sent into every city a warner.1","tr":"Walaw shi/na labaAAathna feekulli qaryatin natheera","juz":19,"page":364},{"s":25,"a":52,"key":"25:52","ar":"فَلَا تُطِعِ ٱلْكَـٰفِرِينَ وَجَـٰهِدْهُم بِهِۦ جِهَادًا كَبِيرًا","en":"So do not obey the disbelievers, and strive against them with it [i.e., the Qur’ān] a great striving.","tr":"Fala tutiAAi alkafireenawajahidhum bihi jihadan kabeera","juz":19,"page":364},{"s":25,"a":53,"key":"25:53","ar":"۞ وَهُوَ ٱلَّذِى مَرَجَ ٱلْبَحْرَيْنِ هَـٰذَا عَذْبٌ فُرَاتٌ وَهَـٰذَا مِلْحٌ أُجَاجٌ وَجَعَلَ بَيْنَهُمَا بَرْزَخًا وَحِجْرًا مَّحْجُورًا","en":"And it is He who has released [simultaneously] the two seas [i.e., bodies of water], one fresh and sweet and one salty and bitter, and He placed between them a barrier and prohibiting partition.","tr":"Wahuwa allathee maraja albahraynihatha AAathbun furatun wahatha milhunojajun wajaAAala baynahuma barzakhan wahijranmahjoora","juz":19,"page":364},{"s":25,"a":54,"key":"25:54","ar":"وَهُوَ ٱلَّذِى خَلَقَ مِنَ ٱلْمَآءِ بَشَرًا فَجَعَلَهُۥ نَسَبًا وَصِهْرًا ۗ وَكَانَ رَبُّكَ قَدِيرًا","en":"And it is He who has created from water [i.e., semen] a human being and made him [a relative by] lineage and marriage. And ever is your Lord competent [concerning creation].","tr":"Wahuwa allathee khalaqa mina alma-ibasharan fajaAAalahu nasaban wasihran wakanarabbuka qadeera","juz":19,"page":364},{"s":25,"a":55,"key":"25:55","ar":"وَيَعْبُدُونَ مِن دُونِ ٱللَّهِ مَا لَا يَنفَعُهُمْ وَلَا يَضُرُّهُمْ ۗ وَكَانَ ٱلْكَافِرُ عَلَىٰ رَبِّهِۦ ظَهِيرًا","en":"But they worship rather than Allāh that which does not benefit them or harm them, and the disbeliever is ever, against his Lord, an assistant [to Satan].","tr":"WayaAAbudoona min dooni Allahi mala yanfaAAuhum wala yadurruhum wakanaalkafiru AAala rabbihi thaheera","juz":19,"page":364},{"s":25,"a":56,"key":"25:56","ar":"وَمَآ أَرْسَلْنَـٰكَ إِلَّا مُبَشِّرًا وَنَذِيرًا","en":"And We have not sent you, [O Muḥammad], except as a bringer of good tidings and a warner.","tr":"Wama arsalnaka illamubashshiran wanatheera","juz":19,"page":365},{"s":25,"a":57,"key":"25:57","ar":"قُلْ مَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ إِلَّا مَن شَآءَ أَن يَتَّخِذَ إِلَىٰ رَبِّهِۦ سَبِيلًا","en":"Say, \"I do not ask of you for it any payment - only that whoever wills might take to his Lord a way.\"","tr":"Qul ma as-alukum AAalayhi min ajrinilla man shaa an yattakhitha ilarabbihi sabeela","juz":19,"page":365},{"s":25,"a":58,"key":"25:58","ar":"وَتَوَكَّلْ عَلَى ٱلْحَىِّ ٱلَّذِى لَا يَمُوتُ وَسَبِّحْ بِحَمْدِهِۦ ۚ وَكَفَىٰ بِهِۦ بِذُنُوبِ عِبَادِهِۦ خَبِيرًا","en":"And rely upon the Ever-Living who does not die, and exalt [Allāh] with His praise. And sufficient is He to be, with the sins of His servants, [fully] Aware -","tr":"Watawakkal AAala alhayyi allatheela yamootu wasabbih bihamdihi wakafabihi bithunoobi AAibadihi khabeera","juz":19,"page":365},{"s":25,"a":59,"key":"25:59","ar":"ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۚ ٱلرَّحْمَـٰنُ فَسْـَٔلْ بِهِۦ خَبِيرًا","en":"He who created the heavens and the earth and what is between them in six days and then established Himself above the Throne1 - the Most Merciful, so ask about Him one well informed [i.e., the Prophet (ﷺ)].","tr":"Allathee khalaqa assamawatiwal-arda wama baynahuma fee sittatiayyamin thumma istawa AAala alAAarshi arrahmanufas-al bihi khabeera","juz":19,"page":365},{"s":25,"a":60,"key":"25:60","ar":"وَإِذَا قِيلَ لَهُمُ ٱسْجُدُوا۟ لِلرَّحْمَـٰنِ قَالُوا۟ وَمَا ٱلرَّحْمَـٰنُ أَنَسْجُدُ لِمَا تَأْمُرُنَا وَزَادَهُمْ نُفُورًا ۩","en":"And when it is said to them, \"Prostrate to the Most Merciful,\" they say, \"And what is the Most Merciful? Should we prostrate to that which you order us?\" And it increases them in aversion.","tr":"Wa-itha qeela lahumu osjudoo lirrahmaniqaloo wama arrahmanu anasjudulima ta/muruna wazadahum nufoora","juz":19,"page":365},{"s":25,"a":61,"key":"25:61","ar":"تَبَارَكَ ٱلَّذِى جَعَلَ فِى ٱلسَّمَآءِ بُرُوجًا وَجَعَلَ فِيهَا سِرَٰجًا وَقَمَرًا مُّنِيرًا","en":"Blessed is He who has placed in the sky great stars and placed therein a [burning] lamp and luminous moon.","tr":"Tabaraka allathee jaAAala feeassama-i buroojan wajaAAala feeha sirajanwaqamaran muneera","juz":19,"page":365},{"s":25,"a":62,"key":"25:62","ar":"وَهُوَ ٱلَّذِى جَعَلَ ٱلَّيْلَ وَٱلنَّهَارَ خِلْفَةً لِّمَنْ أَرَادَ أَن يَذَّكَّرَ أَوْ أَرَادَ شُكُورًا","en":"And it is He who has made the night and the day in succession for whoever desires to remember or desires gratitude.","tr":"Wahuwa allathee jaAAala allayla wannaharakhilfatan liman arada an yaththakkara aw aradashukoora","juz":19,"page":365},{"s":25,"a":63,"key":"25:63","ar":"وَعِبَادُ ٱلرَّحْمَـٰنِ ٱلَّذِينَ يَمْشُونَ عَلَى ٱلْأَرْضِ هَوْنًا وَإِذَا خَاطَبَهُمُ ٱلْجَـٰهِلُونَ قَالُوا۟ سَلَـٰمًا","en":"And the servants of the Most Merciful are those who walk upon the earth easily,1 and when the ignorant address them [harshly], they say [words of] peace,2","tr":"WaAAibadu arrahmaniallatheena yamshoona AAala al-ardi hawnanwa-itha khatabahumu aljahiloona qaloosalama","juz":19,"page":365},{"s":25,"a":64,"key":"25:64","ar":"وَٱلَّذِينَ يَبِيتُونَ لِرَبِّهِمْ سُجَّدًا وَقِيَـٰمًا","en":"And those who spend [part of] the night to their Lord prostrating and standing [in prayer]","tr":"Wallatheena yabeetoonalirabbihim sujjadan waqiyama","juz":19,"page":365},{"s":25,"a":65,"key":"25:65","ar":"وَٱلَّذِينَ يَقُولُونَ رَبَّنَا ٱصْرِفْ عَنَّا عَذَابَ جَهَنَّمَ ۖ إِنَّ عَذَابَهَا كَانَ غَرَامًا","en":"And those who say, \"Our Lord, avert from us the punishment of Hell. Indeed, its punishment is ever adhering;","tr":"Wallatheena yaqooloona rabbanaisrif AAanna AAathaba jahannama inna AAathabahakana gharama","juz":19,"page":365},{"s":25,"a":66,"key":"25:66","ar":"إِنَّهَا سَآءَتْ مُسْتَقَرًّا وَمُقَامًا","en":"Indeed, it is evil as a settlement and residence.\"","tr":"Innaha saat mustaqarran wamuqama","juz":19,"page":365},{"s":25,"a":67,"key":"25:67","ar":"وَٱلَّذِينَ إِذَآ أَنفَقُوا۟ لَمْ يُسْرِفُوا۟ وَلَمْ يَقْتُرُوا۟ وَكَانَ بَيْنَ ذَٰلِكَ قَوَامًا","en":"And [they are] those who, when they spend, do so not excessively or sparingly but are ever, between that, [justly] moderate","tr":"Wallatheena ithaanfaqoo lam yusrifoo walam yaqturoo wakana bayna thalikaqawama","juz":19,"page":365},{"s":25,"a":68,"key":"25:68","ar":"وَٱلَّذِينَ لَا يَدْعُونَ مَعَ ٱللَّهِ إِلَـٰهًا ءَاخَرَ وَلَا يَقْتُلُونَ ٱلنَّفْسَ ٱلَّتِى حَرَّمَ ٱللَّهُ إِلَّا بِٱلْحَقِّ وَلَا يَزْنُونَ ۚ وَمَن يَفْعَلْ ذَٰلِكَ يَلْقَ أَثَامًا","en":"And those who do not invoke1 with Allāh another deity or kill the soul which Allāh has forbidden [to be killed], except by right, and do not commit unlawful sexual intercourse. And whoever should do that will meet a penalty.","tr":"Wallatheena layadAAoona maAAa Allahi ilahan akharawala yaqtuloona annafsa allatee harrama Allahuilla bilhaqqi wala yaznoona wamanyafAAal thalika yalqa athama","juz":19,"page":366},{"s":25,"a":69,"key":"25:69","ar":"يُضَـٰعَفْ لَهُ ٱلْعَذَابُ يَوْمَ ٱلْقِيَـٰمَةِ وَيَخْلُدْ فِيهِۦ مُهَانًا","en":"Multiplied for him is the punishment on the Day of Resurrection, and he will abide therein humiliated -","tr":"YudaAAaf lahu alAAathabu yawmaalqiyamati wayakhlud feehi muhana","juz":19,"page":366},{"s":25,"a":70,"key":"25:70","ar":"إِلَّا مَن تَابَ وَءَامَنَ وَعَمِلَ عَمَلًا صَـٰلِحًا فَأُو۟لَـٰٓئِكَ يُبَدِّلُ ٱللَّهُ سَيِّـَٔاتِهِمْ حَسَنَـٰتٍ ۗ وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًا","en":"Except for those who repent, believe and do righteous work. For them Allāh will replace their evil deeds with good. And ever is Allāh Forgiving and Merciful.","tr":"Illa man taba waamanawaAAamila AAamalan salihan faola-ikayubaddilu Allahu sayyi-atihim hasanatinwakana Allahu ghafooran raheema","juz":19,"page":366},{"s":25,"a":71,"key":"25:71","ar":"وَمَن تَابَ وَعَمِلَ صَـٰلِحًا فَإِنَّهُۥ يَتُوبُ إِلَى ٱللَّهِ مَتَابًا","en":"And he who repents and does righteousness does indeed turn to Allāh with [accepted] repentance.","tr":"Waman taba waAAamila salihanfa-innahu yatoobu ila Allahi mataba","juz":19,"page":366},{"s":25,"a":72,"key":"25:72","ar":"وَٱلَّذِينَ لَا يَشْهَدُونَ ٱلزُّورَ وَإِذَا مَرُّوا۟ بِٱللَّغْوِ مَرُّوا۟ كِرَامًا","en":"And [they are] those who do not testify to falsehood, and when they pass near ill speech, they pass by with dignity.","tr":"Wallatheena layashhadoona azzoora wa-itha marroo billaghwimarroo kirama","juz":19,"page":366},{"s":25,"a":73,"key":"25:73","ar":"وَٱلَّذِينَ إِذَا ذُكِّرُوا۟ بِـَٔايَـٰتِ رَبِّهِمْ لَمْ يَخِرُّوا۟ عَلَيْهَا صُمًّا وَعُمْيَانًا","en":"And those who, when reminded of the verses of their Lord, do not fall upon them deaf and blind.","tr":"Wallatheena itha thukkiroobi-ayati rabbihim lam yakhirroo AAalayha summanwaAAumyana","juz":19,"page":366},{"s":25,"a":74,"key":"25:74","ar":"وَٱلَّذِينَ يَقُولُونَ رَبَّنَا هَبْ لَنَا مِنْ أَزْوَٰجِنَا وَذُرِّيَّـٰتِنَا قُرَّةَ أَعْيُنٍ وَٱجْعَلْنَا لِلْمُتَّقِينَ إِمَامًا","en":"And those who say, \"Our Lord, grant us from among our wives and offspring comfort to our eyes1 and make us a leader [i.e., example] for the righteous.\"","tr":"Wallatheena yaqooloona rabbanahab lana min azwajina wathurriyyatinaqurrata aAAyunin wajAAalna lilmuttaqeena imama","juz":19,"page":366},{"s":25,"a":75,"key":"25:75","ar":"أُو۟لَـٰٓئِكَ يُجْزَوْنَ ٱلْغُرْفَةَ بِمَا صَبَرُوا۟ وَيُلَقَّوْنَ فِيهَا تَحِيَّةً وَسَلَـٰمًا","en":"Those will be awarded the Chamber1 for what they patiently endured, and they will be received therein with greetings and [words of] peace,","tr":"Ola-ika yujzawna alghurfata bimasabaroo wayulaqqawna feeha tahiyyatan wasalama","juz":19,"page":366},{"s":25,"a":76,"key":"25:76","ar":"خَـٰلِدِينَ فِيهَا ۚ حَسُنَتْ مُسْتَقَرًّا وَمُقَامًا","en":"Abiding eternally therein. Good is the settlement and residence.","tr":"Khalideena feeha hasunatmustaqarran wamuqama","juz":19,"page":366},{"s":25,"a":77,"key":"25:77","ar":"قُلْ مَا يَعْبَؤُا۟ بِكُمْ رَبِّى لَوْلَا دُعَآؤُكُمْ ۖ فَقَدْ كَذَّبْتُمْ فَسَوْفَ يَكُونُ لِزَامًۢا","en":"Say, \"What would my Lord care for you if not for your supplication?\"1 For you [disbelievers] have denied, so it [i.e., your denial] is going to be adherent.2","tr":"Qul ma yaAAbao bikum rabbee lawladuAAaokum faqad kaththabtum fasawfa yakoonu lizama","juz":19,"page":366},{"s":26,"a":1,"key":"26:1","ar":" طسٓمٓ","en":"Ṭā, Seen, Meem.1","tr":"Ta-seen-meem","juz":19,"page":367},{"s":26,"a":2,"key":"26:2","ar":"تِلْكَ ءَايَـٰتُ ٱلْكِتَـٰبِ ٱلْمُبِينِ","en":"These are the verses of the clear Book.","tr":"Tilka ayatu alkitabialmubeen","juz":19,"page":367},{"s":26,"a":3,"key":"26:3","ar":"لَعَلَّكَ بَـٰخِعٌ نَّفْسَكَ أَلَّا يَكُونُوا۟ مُؤْمِنِينَ","en":"Perhaps, [O Muḥammad], you would kill yourself with grief that they will not be believers.","tr":"LaAAallaka bakhiAAun nafsaka allayakoonoo mu/mineen","juz":19,"page":367},{"s":26,"a":4,"key":"26:4","ar":"إِن نَّشَأْ نُنَزِّلْ عَلَيْهِم مِّنَ ٱلسَّمَآءِ ءَايَةً فَظَلَّتْ أَعْنَـٰقُهُمْ لَهَا خَـٰضِعِينَ","en":"If We willed, We could send down to them from the sky a sign for which their necks would remain humbled.1","tr":"In nasha/ nunazzil AAalayhim mina assama-iayatan fathallat aAAnaquhum lahakhadiAAeen","juz":19,"page":367},{"s":26,"a":5,"key":"26:5","ar":"وَمَا يَأْتِيهِم مِّن ذِكْرٍ مِّنَ ٱلرَّحْمَـٰنِ مُحْدَثٍ إِلَّا كَانُوا۟ عَنْهُ مُعْرِضِينَ","en":"And no mention [i.e., revelation] comes to them anew from the Most Merciful except that they turn away from it.","tr":"Wama ya/teehim min thikrin minaarrahmani muhdathin illa kanooAAanhu muAArideen","juz":19,"page":367},{"s":26,"a":6,"key":"26:6","ar":"فَقَدْ كَذَّبُوا۟ فَسَيَأْتِيهِمْ أَنۢبَـٰٓؤُا۟ مَا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"For they have already denied, but there will come to them the news of that which they used to ridicule.","tr":"Faqad kaththaboo fasaya/teehim anbaoma kanoo bihi yastahzi-oon","juz":19,"page":367},{"s":26,"a":7,"key":"26:7","ar":"أَوَلَمْ يَرَوْا۟ إِلَى ٱلْأَرْضِ كَمْ أَنۢبَتْنَا فِيهَا مِن كُلِّ زَوْجٍ كَرِيمٍ","en":"Did they not look at the earth - how much We have produced therein from every noble kind?","tr":"Awa lam yaraw ila al-ardi kamanbatna feeha min kulli zawjin kareem","juz":19,"page":367},{"s":26,"a":8,"key":"26:8","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَةً ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ","en":"Indeed in that is a sign, but most of them were not to be believers.","tr":"Inna fee thalika laayatan wamakana aktharuhum mu/mineen","juz":19,"page":367},{"s":26,"a":9,"key":"26:9","ar":"وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"And indeed, your Lord - He is the Exalted in Might, the Merciful.","tr":"Wa-inna rabbaka lahuwa alAAazeezu arraheem","juz":19,"page":367},{"s":26,"a":10,"key":"26:10","ar":"وَإِذْ نَادَىٰ رَبُّكَ مُوسَىٰٓ أَنِ ٱئْتِ ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"And [mention] when your Lord called Moses, [saying], \"Go to the wrongdoing people -","tr":"Wa-ith nada rabbukamoosa ani i/ti alqawma aththalimeen","juz":19,"page":367},{"s":26,"a":11,"key":"26:11","ar":"قَوْمَ فِرْعَوْنَ ۚ أَلَا يَتَّقُونَ","en":"The people of Pharaoh. Will they not fear Allāh?\"","tr":"Qawma firAAawna ala yattaqoon","juz":19,"page":367},{"s":26,"a":12,"key":"26:12","ar":"قَالَ رَبِّ إِنِّىٓ أَخَافُ أَن يُكَذِّبُونِ","en":"He said, \"My Lord, indeed I fear that they will deny me","tr":"Qala rabbi innee akhafu anyukaththiboon","juz":19,"page":367},{"s":26,"a":13,"key":"26:13","ar":"وَيَضِيقُ صَدْرِى وَلَا يَنطَلِقُ لِسَانِى فَأَرْسِلْ إِلَىٰ هَـٰرُونَ","en":"And that my breast will tighten and my tongue will not be fluent, so send for Aaron.","tr":"Wayadeequ sadree walayantaliqu lisanee faarsil ila haroon","juz":19,"page":367},{"s":26,"a":14,"key":"26:14","ar":"وَلَهُمْ عَلَىَّ ذَنۢبٌ فَأَخَافُ أَن يَقْتُلُونِ","en":"And they have upon me a [claim due to] sin, so I fear that they will kill me.\"","tr":"Walahum AAalayya thanbun faakhafuan yaqtuloon","juz":19,"page":367},{"s":26,"a":15,"key":"26:15","ar":"قَالَ كَلَّا ۖ فَٱذْهَبَا بِـَٔايَـٰتِنَآ ۖ إِنَّا مَعَكُم مُّسْتَمِعُونَ","en":"[Allāh] said, \"No. Go both of you with Our signs; indeed, We are with you, listening.","tr":"Qala kalla fathhababi-ayatina inna maAAakum mustamiAAoon","juz":19,"page":367},{"s":26,"a":16,"key":"26:16","ar":"فَأْتِيَا فِرْعَوْنَ فَقُولَآ إِنَّا رَسُولُ رَبِّ ٱلْعَـٰلَمِينَ","en":"Go to Pharaoh and say, 'We are the messengers1 of the Lord of the worlds,","tr":"Fa/tiya firAAawna faqoola innarasoolu rabbi alAAalameen","juz":19,"page":367},{"s":26,"a":17,"key":"26:17","ar":"أَنْ أَرْسِلْ مَعَنَا بَنِىٓ إِسْرَٰٓءِيلَ","en":"[Commanded to say], \"Send with us the Children of Israel.\"'\"","tr":"An arsil maAAana banee isra-eel","juz":19,"page":367},{"s":26,"a":18,"key":"26:18","ar":"قَالَ أَلَمْ نُرَبِّكَ فِينَا وَلِيدًا وَلَبِثْتَ فِينَا مِنْ عُمُرِكَ سِنِينَ","en":"[Pharaoh] said, \"Did we not raise you among us as a child, and you remained among us for years of your life?","tr":"Qala alam nurabbika feenawaleedan walabithta feena min AAumurika sineen","juz":19,"page":367},{"s":26,"a":19,"key":"26:19","ar":"وَفَعَلْتَ فَعْلَتَكَ ٱلَّتِى فَعَلْتَ وَأَنتَ مِنَ ٱلْكَـٰفِرِينَ","en":"And [then] you did your deed which you did,1 and you were of the ungrateful.\"","tr":"WafaAAalta faAAlataka allatee faAAaltawaanta mina alkafireen","juz":19,"page":367},{"s":26,"a":20,"key":"26:20","ar":"قَالَ فَعَلْتُهَآ إِذًا وَأَنَا۠ مِنَ ٱلضَّآلِّينَ","en":"[Moses] said, \"I did it, then, while I was of those astray [i.e., ignorant].","tr":"Qala faAAaltuha ithanwaana mina addalleen","juz":19,"page":368},{"s":26,"a":21,"key":"26:21","ar":"فَفَرَرْتُ مِنكُمْ لَمَّا خِفْتُكُمْ فَوَهَبَ لِى رَبِّى حُكْمًا وَجَعَلَنِى مِنَ ٱلْمُرْسَلِينَ","en":"So I fled from you when I feared you. Then my Lord granted me judgement [i.e., wisdom and prophet hood] and appointed me [as one] of the messengers.","tr":"Fafarartu minkum lamma khiftukumfawahaba lee rabbee hukman wajaAAalanee mina almursaleen","juz":19,"page":368},{"s":26,"a":22,"key":"26:22","ar":"وَتِلْكَ نِعْمَةٌ تَمُنُّهَا عَلَىَّ أَنْ عَبَّدتَّ بَنِىٓ إِسْرَٰٓءِيلَ","en":"And is this a favor of which you remind me - that you have enslaved the Children of Israel?\"","tr":"Watilka niAAmatun tamunnuha AAalayyaan AAabbadta banee isra-eel","juz":19,"page":368},{"s":26,"a":23,"key":"26:23","ar":"قَالَ فِرْعَوْنُ وَمَا رَبُّ ٱلْعَـٰلَمِينَ","en":"Said Pharaoh, \"And what is the Lord of the worlds?\"","tr":"Qala firAAawnu wama rabbu alAAalameen","juz":19,"page":368},{"s":26,"a":24,"key":"26:24","ar":"قَالَ رَبُّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُم مُّوقِنِينَ","en":"[Moses] said, \"The Lord of the heavens and earth and that between them, if you should be convinced.\"","tr":"Qala rabbu assamawatiwal-ardi wama baynahuma in kuntummooqineen","juz":19,"page":368},{"s":26,"a":25,"key":"26:25","ar":"قَالَ لِمَنْ حَوْلَهُۥٓ أَلَا تَسْتَمِعُونَ","en":"[Pharaoh] said to those around him, \"Do you not hear?\"","tr":"Qala liman hawlahu alatastamiAAoon","juz":19,"page":368},{"s":26,"a":26,"key":"26:26","ar":"قَالَ رَبُّكُمْ وَرَبُّ ءَابَآئِكُمُ ٱلْأَوَّلِينَ","en":"[Moses] said, \"Your Lord and the Lord of your first forefathers.\"","tr":"Qala rabbukum warabbu aba-ikumual-awwaleen","juz":19,"page":368},{"s":26,"a":27,"key":"26:27","ar":"قَالَ إِنَّ رَسُولَكُمُ ٱلَّذِىٓ أُرْسِلَ إِلَيْكُمْ لَمَجْنُونٌ","en":"[Pharaoh] said,1 \"Indeed, your 'messenger' who has been sent to you is mad.\"","tr":"Qala inna rasoolakumu allatheeorsila ilaykum lamajnoon","juz":19,"page":368},{"s":26,"a":28,"key":"26:28","ar":"قَالَ رَبُّ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُمْ تَعْقِلُونَ","en":"[Moses] said, \"Lord of the east and the west and that between them, if you were to reason.\"","tr":"Qala rabbu almashriqi walmaghribiwama baynahuma in kuntum taAAqiloon","juz":19,"page":368},{"s":26,"a":29,"key":"26:29","ar":"قَالَ لَئِنِ ٱتَّخَذْتَ إِلَـٰهًا غَيْرِى لَأَجْعَلَنَّكَ مِنَ ٱلْمَسْجُونِينَ","en":"[Pharaoh] said, \"If you take a god other than me, I will surely place you among those imprisoned.\"","tr":"Qala la-ini ittakhathta ilahanghayree laajAAalannaka mina almasjooneen","juz":19,"page":368},{"s":26,"a":30,"key":"26:30","ar":"قَالَ أَوَلَوْ جِئْتُكَ بِشَىْءٍ مُّبِينٍ","en":"[Moses] said, \"Even if I brought you something [i.e., proof] manifest?\"","tr":"Qala awa law ji/tuka bishay-in mubeen","juz":19,"page":368},{"s":26,"a":31,"key":"26:31","ar":"قَالَ فَأْتِ بِهِۦٓ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ","en":"[Pharaoh] said, \"Then bring it, if you should be of the truthful.\"","tr":"Qala fa/ti bihi in kunta mina assadiqeen","juz":19,"page":368},{"s":26,"a":32,"key":"26:32","ar":"فَأَلْقَىٰ عَصَاهُ فَإِذَا هِىَ ثُعْبَانٌ مُّبِينٌ","en":"So [Moses] threw his staff, and suddenly it was a serpent manifest.1","tr":"Faalqa AAasahu fa-ithahiya thuAAbanun mubeen","juz":19,"page":368},{"s":26,"a":33,"key":"26:33","ar":"وَنَزَعَ يَدَهُۥ فَإِذَا هِىَ بَيْضَآءُ لِلنَّـٰظِرِينَ","en":"And he drew out his hand; thereupon it was white for the observers.","tr":"WanazaAAa yadahu fa-itha hiya baydaolinnathireen","juz":19,"page":368},{"s":26,"a":34,"key":"26:34","ar":"قَالَ لِلْمَلَإِ حَوْلَهُۥٓ إِنَّ هَـٰذَا لَسَـٰحِرٌ عَلِيمٌ","en":"[Pharaoh] said to the eminent ones around him, \"Indeed, this is a learned magician.","tr":"Qala lilmala-i hawlahu inna hathalasahirun AAaleem","juz":19,"page":368},{"s":26,"a":35,"key":"26:35","ar":"يُرِيدُ أَن يُخْرِجَكُم مِّنْ أَرْضِكُم بِسِحْرِهِۦ فَمَاذَا تَأْمُرُونَ","en":"He wants to drive you out of your land by his magic, so what do you advise?\"","tr":"Yureedu an yukhrijakum min ardikumbisihrihi famatha ta/muroon","juz":19,"page":368},{"s":26,"a":36,"key":"26:36","ar":"قَالُوٓا۟ أَرْجِهْ وَأَخَاهُ وَٱبْعَثْ فِى ٱلْمَدَآئِنِ حَـٰشِرِينَ","en":"They said, \"Postpone [the matter of] him and his brother and send among the cities gatherers","tr":"Qaloo arjih waakhahu wabAAathfee almada-ini hashireen","juz":19,"page":368},{"s":26,"a":37,"key":"26:37","ar":"يَأْتُوكَ بِكُلِّ سَحَّارٍ عَلِيمٍ","en":"Who will bring you every learned, skilled magician.\"","tr":"Ya/tooka bikulli sahharin AAaleem","juz":19,"page":368},{"s":26,"a":38,"key":"26:38","ar":"فَجُمِعَ ٱلسَّحَرَةُ لِمِيقَـٰتِ يَوْمٍ مَّعْلُومٍ","en":"So the magicians were assembled for the appointment of a well-known day.1","tr":"FajumiAAa assaharatu limeeqatiyawmin maAAloom","juz":19,"page":368},{"s":26,"a":39,"key":"26:39","ar":"وَقِيلَ لِلنَّاسِ هَلْ أَنتُم مُّجْتَمِعُونَ","en":"And it was said to the people, \"Will you congregate.","tr":"Waqeela linnasi hal antummujtamiAAoon","juz":19,"page":368},{"s":26,"a":40,"key":"26:40","ar":"لَعَلَّنَا نَتَّبِعُ ٱلسَّحَرَةَ إِن كَانُوا۟ هُمُ ٱلْغَـٰلِبِينَ","en":"That we might follow the magicians if they are the predominant?\"","tr":"LaAAallana nattabiAAu assaharatain kanoo humu alghalibeen","juz":19,"page":369},{"s":26,"a":41,"key":"26:41","ar":"فَلَمَّا جَآءَ ٱلسَّحَرَةُ قَالُوا۟ لِفِرْعَوْنَ أَئِنَّ لَنَا لَأَجْرًا إِن كُنَّا نَحْنُ ٱلْغَـٰلِبِينَ","en":"And when the magicians arrived, they said to Pharaoh, \"Is there indeed for us a reward if we are the predominant?\"","tr":"Falamma jaa assaharatuqaloo lifirAAawna a-inna lana laajran in kunnanahnu alghalibeen","juz":19,"page":369},{"s":26,"a":42,"key":"26:42","ar":"قَالَ نَعَمْ وَإِنَّكُمْ إِذًا لَّمِنَ ٱلْمُقَرَّبِينَ","en":"He said, \"Yes, and indeed, you will then be of those near [to me].\"","tr":"Qala naAAam wa-innakum ithanlamina almuqarrabeen","juz":19,"page":369},{"s":26,"a":43,"key":"26:43","ar":"قَالَ لَهُم مُّوسَىٰٓ أَلْقُوا۟ مَآ أَنتُم مُّلْقُونَ","en":"Moses said to them, \"Throw whatever you will throw.\"","tr":"Qala lahum moosa alqoo maantum mulqoon","juz":19,"page":369},{"s":26,"a":44,"key":"26:44","ar":"فَأَلْقَوْا۟ حِبَالَهُمْ وَعِصِيَّهُمْ وَقَالُوا۟ بِعِزَّةِ فِرْعَوْنَ إِنَّا لَنَحْنُ ٱلْغَـٰلِبُونَ","en":"So they threw their ropes and their staffs and said, \"By the might of Pharaoh, indeed it is we who are predominant.\"","tr":"Faalqaw hibalahum waAAisiyyahumwaqaloo biAAizzati firAAawna inna lanahnualghaliboon","juz":19,"page":369},{"s":26,"a":45,"key":"26:45","ar":"فَأَلْقَىٰ مُوسَىٰ عَصَاهُ فَإِذَا هِىَ تَلْقَفُ مَا يَأْفِكُونَ","en":"Then Moses threw his staff, and at once it devoured what they falsified.","tr":"Faalqa moosa AAasahufa-itha hiya talqafu ma ya/fikoon","juz":19,"page":369},{"s":26,"a":46,"key":"26:46","ar":"فَأُلْقِىَ ٱلسَّحَرَةُ سَـٰجِدِينَ","en":"So the magicians fell down in prostration [to Allāh].","tr":"Faolqiya assaharatu sajideen","juz":19,"page":369},{"s":26,"a":47,"key":"26:47","ar":"قَالُوٓا۟ ءَامَنَّا بِرَبِّ ٱلْعَـٰلَمِينَ","en":"They said, \"We have believed in the Lord of the worlds,","tr":"Qaloo amanna birabbialAAalameen","juz":19,"page":369},{"s":26,"a":48,"key":"26:48","ar":"رَبِّ مُوسَىٰ وَهَـٰرُونَ","en":"The Lord of Moses and Aaron.\"","tr":"Rabbi moosa waharoon","juz":19,"page":369},{"s":26,"a":49,"key":"26:49","ar":"قَالَ ءَامَنتُمْ لَهُۥ قَبْلَ أَنْ ءَاذَنَ لَكُمْ ۖ إِنَّهُۥ لَكَبِيرُكُمُ ٱلَّذِى عَلَّمَكُمُ ٱلسِّحْرَ فَلَسَوْفَ تَعْلَمُونَ ۚ لَأُقَطِّعَنَّ أَيْدِيَكُمْ وَأَرْجُلَكُم مِّنْ خِلَـٰفٍ وَلَأُصَلِّبَنَّكُمْ أَجْمَعِينَ","en":"[Pharaoh] said, \"You believed him [i.e., Moses] before I gave you permission. Indeed, he is your leader who has taught you magic, but you are going to know. I will surely cut off your hands and your feet on opposite sides, and I will surely crucify you all.\"","tr":"Qala amantum lahu qabla an athanalakum innahu lakabeerukumu allathee AAallamakumu assihrafalasawfa taAAlamoona laoqattiAAanna aydiyakum waarjulakummin khilafin walaosallibannakum ajmaAAeen","juz":19,"page":369},{"s":26,"a":50,"key":"26:50","ar":"قَالُوا۟ لَا ضَيْرَ ۖ إِنَّآ إِلَىٰ رَبِّنَا مُنقَلِبُونَ","en":"They said, \"No harm. Indeed, to our Lord we will return.","tr":"Qaloo la dayra innaila rabbina munqaliboon","juz":19,"page":369},{"s":26,"a":51,"key":"26:51","ar":"إِنَّا نَطْمَعُ أَن يَغْفِرَ لَنَا رَبُّنَا خَطَـٰيَـٰنَآ أَن كُنَّآ أَوَّلَ ٱلْمُؤْمِنِينَ","en":"Indeed, we aspire that our Lord will forgive us our sins because we were the first of the believers.\"","tr":"Inna natmaAAu an yaghfira lanarabbuna khatayana an kunnaawwala almu/mineen","juz":19,"page":369},{"s":26,"a":52,"key":"26:52","ar":"۞ وَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنْ أَسْرِ بِعِبَادِىٓ إِنَّكُم مُّتَّبَعُونَ","en":"And We inspired to Moses, \"Travel by night with My servants; indeed, you will be pursued.\"","tr":"Waawhayna ila moosaan asri biAAibadee innakum muttabaAAoon","juz":19,"page":369},{"s":26,"a":53,"key":"26:53","ar":"فَأَرْسَلَ فِرْعَوْنُ فِى ٱلْمَدَآئِنِ حَـٰشِرِينَ","en":"Then Pharaoh sent among the cities gatherers1","tr":"Faarsala firAAawnu fee almada-ini hashireen","juz":19,"page":369},{"s":26,"a":54,"key":"26:54","ar":"إِنَّ هَـٰٓؤُلَآءِ لَشِرْذِمَةٌ قَلِيلُونَ","en":"[And said], \"Indeed, those are but a small band,","tr":"Inna haola-i lashirthimatunqaleeloon","juz":19,"page":369},{"s":26,"a":55,"key":"26:55","ar":"وَإِنَّهُمْ لَنَا لَغَآئِظُونَ","en":"And indeed, they are enraging us,","tr":"Wa-innahum lana lagha-ithoon","juz":19,"page":369},{"s":26,"a":56,"key":"26:56","ar":"وَإِنَّا لَجَمِيعٌ حَـٰذِرُونَ","en":"And indeed, we are a cautious society...\"","tr":"Wa-inna lajameeAAun hathiroon","juz":19,"page":369},{"s":26,"a":57,"key":"26:57","ar":"فَأَخْرَجْنَـٰهُم مِّن جَنَّـٰتٍ وَعُيُونٍ","en":"So We removed them from gardens and springs","tr":"Faakhrajnahum min jannatinwaAAuyoon","juz":19,"page":369},{"s":26,"a":58,"key":"26:58","ar":"وَكُنُوزٍ وَمَقَامٍ كَرِيمٍ","en":"And treasures and honorable station1 -","tr":"Wakunoozin wamaqamin kareem","juz":19,"page":369},{"s":26,"a":59,"key":"26:59","ar":"كَذَٰلِكَ وَأَوْرَثْنَـٰهَا بَنِىٓ إِسْرَٰٓءِيلَ","en":"Thus. And We caused to inherit it the Children of Israel.","tr":"Kathalika waawrathnahabanee isra-eel","juz":19,"page":369},{"s":26,"a":60,"key":"26:60","ar":"فَأَتْبَعُوهُم مُّشْرِقِينَ","en":"So they pursued them at sunrise.","tr":"FaatbaAAoohum mushriqeen","juz":19,"page":369},{"s":26,"a":61,"key":"26:61","ar":"فَلَمَّا تَرَٰٓءَا ٱلْجَمْعَانِ قَالَ أَصْحَـٰبُ مُوسَىٰٓ إِنَّا لَمُدْرَكُونَ","en":"And when the two companies saw one another, the companions of Moses said, \"Indeed, we are to be overtaken!\"","tr":"Falamma taraa aljamAAaniqala as-habu moosa innalamudrakoon","juz":19,"page":370},{"s":26,"a":62,"key":"26:62","ar":"قَالَ كَلَّآ ۖ إِنَّ مَعِىَ رَبِّى سَيَهْدِينِ","en":"[Moses] said, \"No! Indeed, with me is my Lord; He will guide me.\"","tr":"Qala kalla inna maAAiya rabbeesayahdeen","juz":19,"page":370},{"s":26,"a":63,"key":"26:63","ar":"فَأَوْحَيْنَآ إِلَىٰ مُوسَىٰٓ أَنِ ٱضْرِب بِّعَصَاكَ ٱلْبَحْرَ ۖ فَٱنفَلَقَ فَكَانَ كُلُّ فِرْقٍ كَٱلطَّوْدِ ٱلْعَظِيمِ","en":"Then We inspired to Moses, \"Strike with your staff the sea,\" and it parted, and each portion was like a great towering mountain.","tr":"Faawhayna ila moosaani idrib biAAasaka albahra fanfalaqafakana kullu firqin kattawdi alAAatheem","juz":19,"page":370},{"s":26,"a":64,"key":"26:64","ar":"وَأَزْلَفْنَا ثَمَّ ٱلْـَٔاخَرِينَ","en":"And We advanced thereto the others [i.e., the pursuers].","tr":"Waazlafna thamma al-akhareen","juz":19,"page":370},{"s":26,"a":65,"key":"26:65","ar":"وَأَنجَيْنَا مُوسَىٰ وَمَن مَّعَهُۥٓ أَجْمَعِينَ","en":"And We saved Moses and those with him, all together.","tr":"Waanjayna moosa waman maAAahuajmaAAeen","juz":19,"page":370},{"s":26,"a":66,"key":"26:66","ar":"ثُمَّ أَغْرَقْنَا ٱلْـَٔاخَرِينَ","en":"Then We drowned the others.","tr":"Thumma aghraqna al-akhareen","juz":19,"page":370},{"s":26,"a":67,"key":"26:67","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَةً ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ","en":"Indeed in that is a sign, but most of them were not to be believers.","tr":"Inna fee thalika laayatan wamakana aktharuhum mu/mineen","juz":19,"page":370},{"s":26,"a":68,"key":"26:68","ar":"وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"And indeed, your Lord - He is the Exalted in Might, the Merciful.","tr":"Wa-inna rabbaka lahuwa alAAazeezu arraheem","juz":19,"page":370},{"s":26,"a":69,"key":"26:69","ar":"وَٱتْلُ عَلَيْهِمْ نَبَأَ إِبْرَٰهِيمَ","en":"And recite to them the news of Abraham,","tr":"Watlu AAalayhim nabaa ibraheem","juz":19,"page":370},{"s":26,"a":70,"key":"26:70","ar":"إِذْ قَالَ لِأَبِيهِ وَقَوْمِهِۦ مَا تَعْبُدُونَ","en":"When he said to his father and his people, \"What do you worship?\"","tr":"Ith qala li-abeehi waqawmihi mataAAbudoon","juz":19,"page":370},{"s":26,"a":71,"key":"26:71","ar":"قَالُوا۟ نَعْبُدُ أَصْنَامًا فَنَظَلُّ لَهَا عَـٰكِفِينَ","en":"They said, \"We worship idols and remain to them devoted.\"","tr":"Qaloo naAAbudu asnamanfanathallu laha AAakifeen","juz":19,"page":370},{"s":26,"a":72,"key":"26:72","ar":"قَالَ هَلْ يَسْمَعُونَكُمْ إِذْ تَدْعُونَ","en":"He said, \"Do they hear you when you supplicate?","tr":"Qala hal yasmaAAoonakum ithtadAAoon","juz":19,"page":370},{"s":26,"a":73,"key":"26:73","ar":"أَوْ يَنفَعُونَكُمْ أَوْ يَضُرُّونَ","en":"Or do they benefit you, or do they harm?\"","tr":"Aw yanfaAAoonakum aw yadurroon","juz":19,"page":370},{"s":26,"a":74,"key":"26:74","ar":"قَالُوا۟ بَلْ وَجَدْنَآ ءَابَآءَنَا كَذَٰلِكَ يَفْعَلُونَ","en":"They said, \"But we found our fathers doing thus.\"","tr":"Qaloo bal wajadna abaanakathalika yafAAaloon","juz":19,"page":370},{"s":26,"a":75,"key":"26:75","ar":"قَالَ أَفَرَءَيْتُم مَّا كُنتُمْ تَعْبُدُونَ","en":"He said, \"Then do you see what you have been worshipping,","tr":"Qala afaraaytum ma kuntumtaAAbudoon","juz":19,"page":370},{"s":26,"a":76,"key":"26:76","ar":"أَنتُمْ وَءَابَآؤُكُمُ ٱلْأَقْدَمُونَ","en":"You and your ancient forefathers?","tr":"Antum waabaokumu al-aqdamoon","juz":19,"page":370},{"s":26,"a":77,"key":"26:77","ar":"فَإِنَّهُمْ عَدُوٌّ لِّىٓ إِلَّا رَبَّ ٱلْعَـٰلَمِينَ","en":"Indeed, they are enemies to me, except the Lord of the worlds,1","tr":"Fa-innahum AAaduwwun lee illa rabbaalAAalameen","juz":19,"page":370},{"s":26,"a":78,"key":"26:78","ar":"ٱلَّذِى خَلَقَنِى فَهُوَ يَهْدِينِ","en":"Who created me, and He [it is who] guides me.","tr":"Allathee khalaqanee fahuwa yahdeen","juz":19,"page":370},{"s":26,"a":79,"key":"26:79","ar":"وَٱلَّذِى هُوَ يُطْعِمُنِى وَيَسْقِينِ","en":"And it is He who feeds me and gives me drink.","tr":"Wallathee huwa yutAAimuneewayasqeen","juz":19,"page":370},{"s":26,"a":80,"key":"26:80","ar":"وَإِذَا مَرِضْتُ فَهُوَ يَشْفِينِ","en":"And when I am ill, it is He who cures me","tr":"Wa-itha maridtu fahuwayashfeen","juz":19,"page":370},{"s":26,"a":81,"key":"26:81","ar":"وَٱلَّذِى يُمِيتُنِى ثُمَّ يُحْيِينِ","en":"And who will cause me to die and then bring me to life","tr":"Wallathee yumeetunee thummayuhyeen","juz":19,"page":370},{"s":26,"a":82,"key":"26:82","ar":"وَٱلَّذِىٓ أَطْمَعُ أَن يَغْفِرَ لِى خَطِيٓـَٔتِى يَوْمَ ٱلدِّينِ","en":"And who I aspire that He will forgive me my sin on the Day of Recompense.\"","tr":"Wallathee atmaAAu anyaghfira lee khatee-atee yawma addeen","juz":19,"page":370},{"s":26,"a":83,"key":"26:83","ar":"رَبِّ هَبْ لِى حُكْمًا وَأَلْحِقْنِى بِٱلصَّـٰلِحِينَ","en":"[And he said], \"My Lord, grant me authority and join me with the righteous.","tr":"Rabbi hab lee hukman waalhiqneebissaliheen","juz":19,"page":370},{"s":26,"a":84,"key":"26:84","ar":"وَٱجْعَل لِّى لِسَانَ صِدْقٍ فِى ٱلْـَٔاخِرِينَ","en":"And grant me a mention [i.e., reputation] of honor among later generations.","tr":"WajAAal lee lisana sidqinfee al-akhireen","juz":19,"page":371},{"s":26,"a":85,"key":"26:85","ar":"وَٱجْعَلْنِى مِن وَرَثَةِ جَنَّةِ ٱلنَّعِيمِ","en":"And place me among the inheritors of the Garden of Pleasure.","tr":"WajAAalnee min warathati jannati annaAAeem","juz":19,"page":371},{"s":26,"a":86,"key":"26:86","ar":"وَٱغْفِرْ لِأَبِىٓ إِنَّهُۥ كَانَ مِنَ ٱلضَّآلِّينَ","en":"And forgive my father. Indeed, he has been of those astray.","tr":"Waghfir li-abee innahu kanamina addalleen","juz":19,"page":371},{"s":26,"a":87,"key":"26:87","ar":"وَلَا تُخْزِنِى يَوْمَ يُبْعَثُونَ","en":"And do not disgrace me on the Day they are [all] resurrected -","tr":"Wala tukhzinee yawma yubAAathoon","juz":19,"page":371},{"s":26,"a":88,"key":"26:88","ar":"يَوْمَ لَا يَنفَعُ مَالٌ وَلَا بَنُونَ","en":"The Day when there will not benefit [anyone] wealth or children","tr":"Yawma la yanfaAAu malun walabanoon","juz":19,"page":371},{"s":26,"a":89,"key":"26:89","ar":"إِلَّا مَنْ أَتَى ٱللَّهَ بِقَلْبٍ سَلِيمٍ","en":"But only one who comes to Allāh with a sound heart.\"","tr":"Illa man ata Allahabiqalbin saleem","juz":19,"page":371},{"s":26,"a":90,"key":"26:90","ar":"وَأُزْلِفَتِ ٱلْجَنَّةُ لِلْمُتَّقِينَ","en":"And Paradise will be brought near [that Day] to the righteous.","tr":"Waozlifati aljannatu lilmuttaqeen","juz":19,"page":371},{"s":26,"a":91,"key":"26:91","ar":"وَبُرِّزَتِ ٱلْجَحِيمُ لِلْغَاوِينَ","en":"And Hellfire will be brought forth for the deviators,","tr":"Waburrizati aljaheemu lilghaween","juz":19,"page":371},{"s":26,"a":92,"key":"26:92","ar":"وَقِيلَ لَهُمْ أَيْنَ مَا كُنتُمْ تَعْبُدُونَ","en":"And it will be said to them, \"Where are those you used to worship","tr":"Waqeela lahum ayna ma kuntumtaAAbudoon","juz":19,"page":371},{"s":26,"a":93,"key":"26:93","ar":"مِن دُونِ ٱللَّهِ هَلْ يَنصُرُونَكُمْ أَوْ يَنتَصِرُونَ","en":"Other than Allāh? Can they help you or help themselves?\"","tr":"Min dooni Allahi hal yansuroonakumaw yantasiroon","juz":19,"page":371},{"s":26,"a":94,"key":"26:94","ar":"فَكُبْكِبُوا۟ فِيهَا هُمْ وَٱلْغَاوُۥنَ","en":"So they will be overturned into it [i.e., Hellfire], they and the deviators","tr":"Fakubkiboo feeha hum walghawoon","juz":19,"page":371},{"s":26,"a":95,"key":"26:95","ar":"وَجُنُودُ إِبْلِيسَ أَجْمَعُونَ","en":"And the soldiers of Iblees, all together.","tr":"Wajunoodu ibleesa ajmaAAoon","juz":19,"page":371},{"s":26,"a":96,"key":"26:96","ar":"قَالُوا۟ وَهُمْ فِيهَا يَخْتَصِمُونَ","en":"They will say while they dispute therein,","tr":"Qaloo wahum feeha yakhtasimoon","juz":19,"page":371},{"s":26,"a":97,"key":"26:97","ar":"تَٱللَّهِ إِن كُنَّا لَفِى ضَلَـٰلٍ مُّبِينٍ","en":"\"By Allāh, we were indeed in manifest error","tr":"Tallahi in kunna lafeedalalin mubeen","juz":19,"page":371},{"s":26,"a":98,"key":"26:98","ar":"إِذْ نُسَوِّيكُم بِرَبِّ ٱلْعَـٰلَمِينَ","en":"When we equated you with the Lord of the worlds.","tr":"Ith nusawweekum birabbi alAAalameen","juz":19,"page":371},{"s":26,"a":99,"key":"26:99","ar":"وَمَآ أَضَلَّنَآ إِلَّا ٱلْمُجْرِمُونَ","en":"And no one misguided us except the criminals.","tr":"Wama adallana illaalmujrimoon","juz":19,"page":371},{"s":26,"a":100,"key":"26:100","ar":"فَمَا لَنَا مِن شَـٰفِعِينَ","en":"So now we have no intercessors","tr":"Fama lana min shafiAAeen","juz":19,"page":371},{"s":26,"a":101,"key":"26:101","ar":"وَلَا صَدِيقٍ حَمِيمٍ","en":"And not a devoted friend.","tr":"Wala sadeeqin hameem","juz":19,"page":371},{"s":26,"a":102,"key":"26:102","ar":"فَلَوْ أَنَّ لَنَا كَرَّةً فَنَكُونَ مِنَ ٱلْمُؤْمِنِينَ","en":"Then if we only had a return [to the world] and could be of the believers...\"1","tr":"Falaw anna lana karratan fanakoonamina almu/mineen","juz":19,"page":371},{"s":26,"a":103,"key":"26:103","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَةً ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ","en":"Indeed in that is a sign, but most of them were not to be believers.","tr":"Inna fee thalika laayatan wamakana aktharuhum mu/mineen","juz":19,"page":371},{"s":26,"a":104,"key":"26:104","ar":"وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"And indeed, your Lord - He is the Exalted in Might, the Merciful.","tr":"Wa-inna rabbaka lahuwa alAAazeezu arraheem","juz":19,"page":371},{"s":26,"a":105,"key":"26:105","ar":"كَذَّبَتْ قَوْمُ نُوحٍ ٱلْمُرْسَلِينَ","en":"The people of Noah denied the messengers1","tr":"Kaththabat qawmu noohinalmursaleen","juz":19,"page":371},{"s":26,"a":106,"key":"26:106","ar":"إِذْ قَالَ لَهُمْ أَخُوهُمْ نُوحٌ أَلَا تَتَّقُونَ","en":"When their brother Noah said to them, \"Will you not fear Allāh?","tr":"Ith qala lahum akhoohum noohunala tattaqoon","juz":19,"page":371},{"s":26,"a":107,"key":"26:107","ar":"إِنِّى لَكُمْ رَسُولٌ أَمِينٌ","en":"Indeed, I am to you a trustworthy messenger.","tr":"Innee lakum rasoolun ameen","juz":19,"page":371},{"s":26,"a":108,"key":"26:108","ar":"فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"So fear Allāh and obey me.","tr":"Fattaqoo Allaha waateeAAoon","juz":19,"page":371},{"s":26,"a":109,"key":"26:109","ar":"وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَـٰلَمِينَ","en":"And I do not ask you for it any payment. My payment is only from the Lord of the worlds.","tr":"Wama as-alukum AAalayhi min ajrin inajriya illa AAala rabbi alAAalameen","juz":19,"page":371},{"s":26,"a":110,"key":"26:110","ar":"فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"So fear Allāh and obey me.\"","tr":"Fattaqoo Allaha waateeAAoon","juz":19,"page":371},{"s":26,"a":111,"key":"26:111","ar":"۞ قَالُوٓا۟ أَنُؤْمِنُ لَكَ وَٱتَّبَعَكَ ٱلْأَرْذَلُونَ","en":"They said, \"Should we believe you while you are followed by the lowest [class of people]?\"","tr":"Qaloo anu/minu laka wattabaAAakaal-arthaloon","juz":19,"page":371},{"s":26,"a":112,"key":"26:112","ar":"قَالَ وَمَا عِلْمِى بِمَا كَانُوا۟ يَعْمَلُونَ","en":"He said, \"And what is my knowledge of what they used to do?","tr":"Qala wama AAilmee bimakanoo yaAAmaloon","juz":19,"page":372},{"s":26,"a":113,"key":"26:113","ar":"إِنْ حِسَابُهُمْ إِلَّا عَلَىٰ رَبِّى ۖ لَوْ تَشْعُرُونَ","en":"Their account is only upon my Lord, if you [could] perceive.","tr":"In hisabuhum illa AAalarabbee law tashAAuroon","juz":19,"page":372},{"s":26,"a":114,"key":"26:114","ar":"وَمَآ أَنَا۠ بِطَارِدِ ٱلْمُؤْمِنِينَ","en":"And I am not one to drive away the believers.","tr":"Wama ana bitaridialmu/mineen","juz":19,"page":372},{"s":26,"a":115,"key":"26:115","ar":"إِنْ أَنَا۠ إِلَّا نَذِيرٌ مُّبِينٌ","en":"I am only a clear warner.\"","tr":"In ana illa natheerunmubeen","juz":19,"page":372},{"s":26,"a":116,"key":"26:116","ar":"قَالُوا۟ لَئِن لَّمْ تَنتَهِ يَـٰنُوحُ لَتَكُونَنَّ مِنَ ٱلْمَرْجُومِينَ","en":"They said, \"If you do not desist, O Noah, you will surely be of those who are stoned.\"","tr":"Qaloo la-in lam tantahi yanoohu latakoonanna mina almarjoomeen","juz":19,"page":372},{"s":26,"a":117,"key":"26:117","ar":"قَالَ رَبِّ إِنَّ قَوْمِى كَذَّبُونِ","en":"He said, \"My Lord, indeed my people have denied me.","tr":"Qala rabbi inna qawmee kaththaboon","juz":19,"page":372},{"s":26,"a":118,"key":"26:118","ar":"فَٱفْتَحْ بَيْنِى وَبَيْنَهُمْ فَتْحًا وَنَجِّنِى وَمَن مَّعِىَ مِنَ ٱلْمُؤْمِنِينَ","en":"Then judge between me and them with decisive judgement and save me and those with me of the believers.\"","tr":"Faftah baynee wabaynahum fathanwanajjinee waman maAAiya mina almu/mineen","juz":19,"page":372},{"s":26,"a":119,"key":"26:119","ar":"فَأَنجَيْنَـٰهُ وَمَن مَّعَهُۥ فِى ٱلْفُلْكِ ٱلْمَشْحُونِ","en":"So We saved him and those with him in the laden ship.","tr":"Faanjaynahu waman maAAahu feealfulki almashhoon","juz":19,"page":372},{"s":26,"a":120,"key":"26:120","ar":"ثُمَّ أَغْرَقْنَا بَعْدُ ٱلْبَاقِينَ","en":"Then We drowned thereafter the remaining ones.","tr":"Thumma aghraqna baAAdu albaqeen","juz":19,"page":372},{"s":26,"a":121,"key":"26:121","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَةً ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ","en":"Indeed in that is a sign, but most of them were not to be believers.","tr":"Inna fee thalika laayatan wamakana aktharuhum mu/mineen","juz":19,"page":372},{"s":26,"a":122,"key":"26:122","ar":"وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"And indeed, your Lord - He is the Exalted in Might, the Merciful.","tr":"Wa-inna rabbaka lahuwa alAAazeezu arraheem","juz":19,"page":372},{"s":26,"a":123,"key":"26:123","ar":"كَذَّبَتْ عَادٌ ٱلْمُرْسَلِينَ","en":"ʿAad denied the messengers","tr":"Kaththabat AAadun almursaleen","juz":19,"page":372},{"s":26,"a":124,"key":"26:124","ar":"إِذْ قَالَ لَهُمْ أَخُوهُمْ هُودٌ أَلَا تَتَّقُونَ","en":"When their brother Hūd said to them, \"Will you not fear Allāh?","tr":"Ith qala lahum akhoohumhoodun ala tattaqoon","juz":19,"page":372},{"s":26,"a":125,"key":"26:125","ar":"إِنِّى لَكُمْ رَسُولٌ أَمِينٌ","en":"Indeed, I am to you a trustworthy messenger.","tr":"Innee lakum rasoolun ameen","juz":19,"page":372},{"s":26,"a":126,"key":"26:126","ar":"فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"So fear Allāh and obey me.","tr":"Fattaqoo Allaha waateeAAoon","juz":19,"page":372},{"s":26,"a":127,"key":"26:127","ar":"وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَـٰلَمِينَ","en":"And I do not ask you for it any payment. My payment is only from the Lord of the worlds.","tr":"Wama as-alukum AAalayhi min ajrin inajriya illa AAala rabbi alAAalameen","juz":19,"page":372},{"s":26,"a":128,"key":"26:128","ar":"أَتَبْنُونَ بِكُلِّ رِيعٍ ءَايَةً تَعْبَثُونَ","en":"Do you construct on every elevation a sign,1 amusing yourselves,","tr":"Atabnoona bikulli reeAAin ayatantaAAbathoon","juz":19,"page":372},{"s":26,"a":129,"key":"26:129","ar":"وَتَتَّخِذُونَ مَصَانِعَ لَعَلَّكُمْ تَخْلُدُونَ","en":"And take for yourselves constructions [i.e., palaces and fortresses] that you might abide eternally?","tr":"Watattakhithoona masaniAAalaAAallakum takhludoon","juz":19,"page":372},{"s":26,"a":130,"key":"26:130","ar":"وَإِذَا بَطَشْتُم بَطَشْتُمْ جَبَّارِينَ","en":"And when you strike, you strike as tyrants.","tr":"Wa-itha batashtum batashtumjabbareen","juz":19,"page":372},{"s":26,"a":131,"key":"26:131","ar":"فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"So fear Allāh and obey me.","tr":"Fattaqoo Allaha waateeAAoon","juz":19,"page":372},{"s":26,"a":132,"key":"26:132","ar":"وَٱتَّقُوا۟ ٱلَّذِىٓ أَمَدَّكُم بِمَا تَعْلَمُونَ","en":"And fear He who provided you with that which you know,","tr":"Wattaqoo allathee amaddakumbima taAAlamoon","juz":19,"page":372},{"s":26,"a":133,"key":"26:133","ar":"أَمَدَّكُم بِأَنْعَـٰمٍ وَبَنِينَ","en":"Provided you with grazing livestock and children","tr":"Amaddakum bi-anAAamin wabaneen","juz":19,"page":372},{"s":26,"a":134,"key":"26:134","ar":"وَجَنَّـٰتٍ وَعُيُونٍ","en":"And gardens and springs.","tr":"Wajannatin waAAuyoon","juz":19,"page":372},{"s":26,"a":135,"key":"26:135","ar":"إِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ عَظِيمٍ","en":"Indeed, I fear for you the punishment of a terrible day.\"","tr":"Innee akhafu AAalaykum AAathabayawmin AAatheem","juz":19,"page":372},{"s":26,"a":136,"key":"26:136","ar":"قَالُوا۟ سَوَآءٌ عَلَيْنَآ أَوَعَظْتَ أَمْ لَمْ تَكُن مِّنَ ٱلْوَٰعِظِينَ","en":"They said, \"It is all the same to us whether you advise or are not of the advisors.","tr":"Qaloo sawaon AAalaynaawaAAathta am lam takun mina alwaAAitheen","juz":19,"page":372},{"s":26,"a":137,"key":"26:137","ar":"إِنْ هَـٰذَآ إِلَّا خُلُقُ ٱلْأَوَّلِينَ","en":"This is not but the custom of the former peoples,","tr":"In hatha illa khuluqual-awwaleen","juz":19,"page":373},{"s":26,"a":138,"key":"26:138","ar":"وَمَا نَحْنُ بِمُعَذَّبِينَ","en":"And we are not to be punished.\"","tr":"Wama nahnu bimuAAaththabeen","juz":19,"page":373},{"s":26,"a":139,"key":"26:139","ar":"فَكَذَّبُوهُ فَأَهْلَكْنَـٰهُمْ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ","en":"And they denied him, so We destroyed them. Indeed in that is a sign, but most of them were not to be believers.","tr":"Fakaththaboohu faahlaknahuminna fee thalika laayatan wama kanaaktharuhum mu/mineen","juz":19,"page":373},{"s":26,"a":140,"key":"26:140","ar":"وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"And indeed, your Lord - He is the Exalted in Might, the Merciful.","tr":"Wa-inna rabbaka lahuwa alAAazeezu arraheem","juz":19,"page":373},{"s":26,"a":141,"key":"26:141","ar":"كَذَّبَتْ ثَمُودُ ٱلْمُرْسَلِينَ","en":"Thamūd denied the messengers","tr":"Kaththabat thamoodu almursaleen","juz":19,"page":373},{"s":26,"a":142,"key":"26:142","ar":"إِذْ قَالَ لَهُمْ أَخُوهُمْ صَـٰلِحٌ أَلَا تَتَّقُونَ","en":"When their brother Ṣāliḥ said to them, \"Will you not fear Allāh?","tr":"Ith qala lahum akhoohum salihunala tattaqoon","juz":19,"page":373},{"s":26,"a":143,"key":"26:143","ar":"إِنِّى لَكُمْ رَسُولٌ أَمِينٌ","en":"Indeed, I am to you a trustworthy messenger.","tr":"Innee lakum rasoolun ameen","juz":19,"page":373},{"s":26,"a":144,"key":"26:144","ar":"فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"So fear Allāh and obey me.","tr":"Fattaqoo Allaha waateeAAoon","juz":19,"page":373},{"s":26,"a":145,"key":"26:145","ar":"وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَـٰلَمِينَ","en":"And I do not ask you for it any payment. My payment is only from the Lord of the worlds.","tr":"Wama as-alukum AAalayhi min ajrin inajriya illa AAala rabbi alAAalameen","juz":19,"page":373},{"s":26,"a":146,"key":"26:146","ar":"أَتُتْرَكُونَ فِى مَا هَـٰهُنَآ ءَامِنِينَ","en":"Will you be left in what is here, secure [from death],","tr":"Atutrakoona fee ma hahunaamineen","juz":19,"page":373},{"s":26,"a":147,"key":"26:147","ar":"فِى جَنَّـٰتٍ وَعُيُونٍ","en":"Within gardens and springs","tr":"Fee jannatin waAAuyoon","juz":19,"page":373},{"s":26,"a":148,"key":"26:148","ar":"وَزُرُوعٍ وَنَخْلٍ طَلْعُهَا هَضِيمٌ","en":"And fields of crops and palm trees with softened fruit?","tr":"WazurooAAin wanakhlin talAAuhahadeem","juz":19,"page":373},{"s":26,"a":149,"key":"26:149","ar":"وَتَنْحِتُونَ مِنَ ٱلْجِبَالِ بُيُوتًا فَـٰرِهِينَ","en":"And you carve out of the mountains, homes, with skill.","tr":"Watanhitoona mina aljibalibuyootan fariheen","juz":19,"page":373},{"s":26,"a":150,"key":"26:150","ar":"فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"So fear Allāh and obey me.","tr":"Fattaqoo Allaha waateeAAoon","juz":19,"page":373},{"s":26,"a":151,"key":"26:151","ar":"وَلَا تُطِيعُوٓا۟ أَمْرَ ٱلْمُسْرِفِينَ","en":"And do not obey the order of the transgressors,","tr":"Wala tuteeAAoo amraalmusrifeen","juz":19,"page":373},{"s":26,"a":152,"key":"26:152","ar":"ٱلَّذِينَ يُفْسِدُونَ فِى ٱلْأَرْضِ وَلَا يُصْلِحُونَ","en":"Who cause corruption in the land and do not amend.\"","tr":"Allatheena yufsidoona fee al-ardiwala yuslihoon","juz":19,"page":373},{"s":26,"a":153,"key":"26:153","ar":"قَالُوٓا۟ إِنَّمَآ أَنتَ مِنَ ٱلْمُسَحَّرِينَ","en":"They said, \"You are only of those affected by magic.","tr":"Qaloo innama anta mina almusahhareen","juz":19,"page":373},{"s":26,"a":154,"key":"26:154","ar":"مَآ أَنتَ إِلَّا بَشَرٌ مِّثْلُنَا فَأْتِ بِـَٔايَةٍ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ","en":"You are but a man like ourselves, so bring a sign, if you should be of the truthful.\"","tr":"Ma anta illa basharun mithlunafa/ti bi-ayatin in kunta mina assadiqeena","juz":19,"page":373},{"s":26,"a":155,"key":"26:155","ar":"قَالَ هَـٰذِهِۦ نَاقَةٌ لَّهَا شِرْبٌ وَلَكُمْ شِرْبُ يَوْمٍ مَّعْلُومٍ","en":"He said, \"This is a she-camel.1 For her is a [time of] drink, and for you is a [time of] drink, [each] on a known day.","tr":"Qala hathihi naqatunlaha shirbun walakum shirbu yawmin maAAloom","juz":19,"page":373},{"s":26,"a":156,"key":"26:156","ar":"وَلَا تَمَسُّوهَا بِسُوٓءٍ فَيَأْخُذَكُمْ عَذَابُ يَوْمٍ عَظِيمٍ","en":"And do not touch her with harm, lest you be seized by the punishment of a terrible day.\"","tr":"Wala tamassooha bisoo-infaya/khuthakum AAathabu yawmin AAatheem","juz":19,"page":373},{"s":26,"a":157,"key":"26:157","ar":"فَعَقَرُوهَا فَأَصْبَحُوا۟ نَـٰدِمِينَ","en":"But they hamstrung her and so became regretful.","tr":"FaAAaqarooha faasbahoonadimeen","juz":19,"page":373},{"s":26,"a":158,"key":"26:158","ar":"فَأَخَذَهُمُ ٱلْعَذَابُ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ","en":"And the punishment seized them. Indeed in that is a sign, but most of them were not to be believers.","tr":"Faakhathahumu alAAathabu innafee thalika laayatan wama kanaaktharuhum mu/mineen","juz":19,"page":373},{"s":26,"a":159,"key":"26:159","ar":"وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"And indeed, your Lord - He is the Exalted in Might, the Merciful.","tr":"Wa-inna rabbaka lahuwa alAAazeezu arraheem","juz":19,"page":373},{"s":26,"a":160,"key":"26:160","ar":"كَذَّبَتْ قَوْمُ لُوطٍ ٱلْمُرْسَلِينَ","en":"The people of Lot denied the messengers","tr":"Kaththabat qawmu lootinalmursaleen","juz":19,"page":374},{"s":26,"a":161,"key":"26:161","ar":"إِذْ قَالَ لَهُمْ أَخُوهُمْ لُوطٌ أَلَا تَتَّقُونَ","en":"When their brother Lot said to them, \"Will you not fear Allāh?","tr":"Ith qala lahum akhoohum lootunala tattaqoon","juz":19,"page":374},{"s":26,"a":162,"key":"26:162","ar":"إِنِّى لَكُمْ رَسُولٌ أَمِينٌ","en":"Indeed, I am to you a trustworthy messenger.","tr":"Innee lakum rasoolun ameen","juz":19,"page":374},{"s":26,"a":163,"key":"26:163","ar":"فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"So fear Allāh and obey me.","tr":"Fattaqoo Allaha waateeAAoon","juz":19,"page":374},{"s":26,"a":164,"key":"26:164","ar":"وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَـٰلَمِينَ","en":"And I do not ask you for it any payment. My payment is only from the Lord of the worlds.","tr":"Wama as-alukum AAalayhi min ajrin inajriya illa AAala rabbi alAAalameen","juz":19,"page":374},{"s":26,"a":165,"key":"26:165","ar":"أَتَأْتُونَ ٱلذُّكْرَانَ مِنَ ٱلْعَـٰلَمِينَ","en":"Do you approach males among the worlds1","tr":"Ata/toona aththukranamina alAAalameen","juz":19,"page":374},{"s":26,"a":166,"key":"26:166","ar":"وَتَذَرُونَ مَا خَلَقَ لَكُمْ رَبُّكُم مِّنْ أَزْوَٰجِكُم ۚ بَلْ أَنتُمْ قَوْمٌ عَادُونَ","en":"And leave what your Lord has created for you as mates? But you are a people transgressing.\"","tr":"Watatharoona ma khalaqa lakumrabbukum min azwajikum bal antum qawmun AAadoon","juz":19,"page":374},{"s":26,"a":167,"key":"26:167","ar":"قَالُوا۟ لَئِن لَّمْ تَنتَهِ يَـٰلُوطُ لَتَكُونَنَّ مِنَ ٱلْمُخْرَجِينَ","en":"They said, \"If you do not desist, O Lot, you will surely be of those evicted.\"","tr":"Qaloo la-in lam tantahi yalootu latakoonanna mina almukhrajeen","juz":19,"page":374},{"s":26,"a":168,"key":"26:168","ar":"قَالَ إِنِّى لِعَمَلِكُم مِّنَ ٱلْقَالِينَ","en":"He said, \"Indeed, I am, toward your deed, of those who detest [it].","tr":"Qala innee liAAamalikum mina alqaleen","juz":19,"page":374},{"s":26,"a":169,"key":"26:169","ar":"رَبِّ نَجِّنِى وَأَهْلِى مِمَّا يَعْمَلُونَ","en":"My Lord, save me and my family from [the consequence of] what they do.\"","tr":"Rabbi najjinee waahlee mimmayaAAmaloon","juz":19,"page":374},{"s":26,"a":170,"key":"26:170","ar":"فَنَجَّيْنَـٰهُ وَأَهْلَهُۥٓ أَجْمَعِينَ","en":"So We saved him and his family, all,","tr":"Fanajjaynahu waahlahu ajmaAAeen","juz":19,"page":374},{"s":26,"a":171,"key":"26:171","ar":"إِلَّا عَجُوزًا فِى ٱلْغَـٰبِرِينَ","en":"Except an old woman1 among those who remained behind.","tr":"Illa AAajoozan fee alghabireen","juz":19,"page":374},{"s":26,"a":172,"key":"26:172","ar":"ثُمَّ دَمَّرْنَا ٱلْـَٔاخَرِينَ","en":"Then We destroyed the others.","tr":"Thumma dammarna al-akhareen","juz":19,"page":374},{"s":26,"a":173,"key":"26:173","ar":"وَأَمْطَرْنَا عَلَيْهِم مَّطَرًا ۖ فَسَآءَ مَطَرُ ٱلْمُنذَرِينَ","en":"And We rained upon them a rain [of stones], and evil was the rain of those who were warned.","tr":"Waamtarna AAalayhim mataranfasaa mataru almunthareen","juz":19,"page":374},{"s":26,"a":174,"key":"26:174","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَةً ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ","en":"Indeed in that is a sign, but most of them were not to be believers.","tr":"Inna fee thalika laayatan wamakana aktharuhum mu/mineen","juz":19,"page":374},{"s":26,"a":175,"key":"26:175","ar":"وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"And indeed, your Lord - He is the Exalted in Might, the Merciful.","tr":"Wa-inna rabbaka lahuwa alAAazeezu arraheem","juz":19,"page":374},{"s":26,"a":176,"key":"26:176","ar":"كَذَّبَ أَصْحَـٰبُ لْـَٔيْكَةِ ٱلْمُرْسَلِينَ","en":"The companions of the thicket [i.e., the people of Madyan] denied the messengers","tr":"Kaththaba as-habual-aykati almursaleen","juz":19,"page":374},{"s":26,"a":177,"key":"26:177","ar":"إِذْ قَالَ لَهُمْ شُعَيْبٌ أَلَا تَتَّقُونَ","en":"When Shuʿayb said to them, \"Will you not fear Allāh?","tr":"Ith qala lahum shuAAaybun alatattaqoon","juz":19,"page":374},{"s":26,"a":178,"key":"26:178","ar":"إِنِّى لَكُمْ رَسُولٌ أَمِينٌ","en":"Indeed, I am to you a trustworthy messenger.","tr":"Innee lakum rasoolun ameen","juz":19,"page":374},{"s":26,"a":179,"key":"26:179","ar":"فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"So fear Allāh and obey me.","tr":"Fattaqoo Allaha waateeAAoon","juz":19,"page":374},{"s":26,"a":180,"key":"26:180","ar":"وَمَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ ۖ إِنْ أَجْرِىَ إِلَّا عَلَىٰ رَبِّ ٱلْعَـٰلَمِينَ","en":"And I do not ask you for it any payment. My payment is only from the Lord of the worlds.","tr":"Wama as-alukum AAalayhi min ajrin inajriya illa AAala rabbi alAAalameen","juz":19,"page":374},{"s":26,"a":181,"key":"26:181","ar":"۞ أَوْفُوا۟ ٱلْكَيْلَ وَلَا تَكُونُوا۟ مِنَ ٱلْمُخْسِرِينَ","en":"Give full measure and do not be of those who cause loss.","tr":"Awfoo alkayla wala takoonoo minaalmukhsireen","juz":19,"page":374},{"s":26,"a":182,"key":"26:182","ar":"وَزِنُوا۟ بِٱلْقِسْطَاسِ ٱلْمُسْتَقِيمِ","en":"And weigh with an even [i.e., honest] balance.","tr":"Wazinoo bilqistasialmustaqeem","juz":19,"page":374},{"s":26,"a":183,"key":"26:183","ar":"وَلَا تَبْخَسُوا۟ ٱلنَّاسَ أَشْيَآءَهُمْ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ","en":"And do not deprive people of their due and do not commit abuse on earth, spreading corruption.","tr":"Wala tabkhasoo annasaashyaahum wala taAAthaw fee al-ardimufsideen","juz":19,"page":374},{"s":26,"a":184,"key":"26:184","ar":"وَٱتَّقُوا۟ ٱلَّذِى خَلَقَكُمْ وَٱلْجِبِلَّةَ ٱلْأَوَّلِينَ","en":"And fear He who created you and the former creation.\"1","tr":"Wattaqoo allathee khalaqakumwaljibillata al-awwaleen","juz":19,"page":375},{"s":26,"a":185,"key":"26:185","ar":"قَالُوٓا۟ إِنَّمَآ أَنتَ مِنَ ٱلْمُسَحَّرِينَ","en":"They said, \"You are only of those affected by magic.","tr":"Qaloo innama anta mina almusahhareen","juz":19,"page":375},{"s":26,"a":186,"key":"26:186","ar":"وَمَآ أَنتَ إِلَّا بَشَرٌ مِّثْلُنَا وَإِن نَّظُنُّكَ لَمِنَ ٱلْكَـٰذِبِينَ","en":"You are but a man like ourselves, and indeed, we think you are among the liars.","tr":"Wama anta illa basharunmithluna wa-in nathunnuka lamina alkathibeen","juz":19,"page":375},{"s":26,"a":187,"key":"26:187","ar":"فَأَسْقِطْ عَلَيْنَا كِسَفًا مِّنَ ٱلسَّمَآءِ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ","en":"So cause to fall upon us fragments of the sky, if you should be of the truthful.\"","tr":"Faasqit AAalayna kisafan minaassama-i in kunta mina assadiqeen","juz":19,"page":375},{"s":26,"a":188,"key":"26:188","ar":"قَالَ رَبِّىٓ أَعْلَمُ بِمَا تَعْمَلُونَ","en":"He said, \"My Lord is most knowing of what you do.\"","tr":"Qala rabbee aAAlamu bimataAAmaloon","juz":19,"page":375},{"s":26,"a":189,"key":"26:189","ar":"فَكَذَّبُوهُ فَأَخَذَهُمْ عَذَابُ يَوْمِ ٱلظُّلَّةِ ۚ إِنَّهُۥ كَانَ عَذَابَ يَوْمٍ عَظِيمٍ","en":"And they denied him, so the punishment of the day of the black cloud seized them. Indeed, it was the punishment of a terrible day.","tr":"Fakaththaboohu faakhathahumAAathabu yawmi aththullati innahu kanaAAathaba yawmin AAatheem","juz":19,"page":375},{"s":26,"a":190,"key":"26:190","ar":"إِنَّ فِى ذَٰلِكَ لَـَٔايَةً ۖ وَمَا كَانَ أَكْثَرُهُم مُّؤْمِنِينَ","en":"Indeed in that is a sign, but most of them were not to be believers.","tr":"Inna fee thalika laayatan wamakana aktharuhum mu/mineen","juz":19,"page":375},{"s":26,"a":191,"key":"26:191","ar":"وَإِنَّ رَبَّكَ لَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"And indeed, your Lord - He is the Exalted in Might, the Merciful.","tr":"Wa-inna rabbaka lahuwa alAAazeezu arraheem","juz":19,"page":375},{"s":26,"a":192,"key":"26:192","ar":"وَإِنَّهُۥ لَتَنزِيلُ رَبِّ ٱلْعَـٰلَمِينَ","en":"And indeed, it [i.e., the Qur’ān] is the revelation of the Lord of the worlds.","tr":"Wa-innahu latanzeelu rabbi alAAalameen","juz":19,"page":375},{"s":26,"a":193,"key":"26:193","ar":"نَزَلَ بِهِ ٱلرُّوحُ ٱلْأَمِينُ","en":"The Trustworthy Spirit [i.e., Gabriel] has brought it down","tr":"Nazala bihi arroohu al-ameen","juz":19,"page":375},{"s":26,"a":194,"key":"26:194","ar":"عَلَىٰ قَلْبِكَ لِتَكُونَ مِنَ ٱلْمُنذِرِينَ","en":"Upon your heart, [O Muḥammad] - that you may be of the warners -","tr":"AAala qalbika litakoona mina almunthireen","juz":19,"page":375},{"s":26,"a":195,"key":"26:195","ar":"بِلِسَانٍ عَرَبِىٍّ مُّبِينٍ","en":"In a clear Arabic language.","tr":"Bilisanin AAarabiyyin mubeen","juz":19,"page":375},{"s":26,"a":196,"key":"26:196","ar":"وَإِنَّهُۥ لَفِى زُبُرِ ٱلْأَوَّلِينَ","en":"And indeed, it is [mentioned] in the scriptures of former peoples.","tr":"Wa-innahu lafee zuburi al-awwaleen","juz":19,"page":375},{"s":26,"a":197,"key":"26:197","ar":"أَوَلَمْ يَكُن لَّهُمْ ءَايَةً أَن يَعْلَمَهُۥ عُلَمَـٰٓؤُا۟ بَنِىٓ إِسْرَٰٓءِيلَ","en":"And has it not been a sign to them that it is recognized by the scholars of the Children of Israel?","tr":"Awa lam yakun lahum ayatan anyaAAlamahu AAulamao banee isra-eel","juz":19,"page":375},{"s":26,"a":198,"key":"26:198","ar":"وَلَوْ نَزَّلْنَـٰهُ عَلَىٰ بَعْضِ ٱلْأَعْجَمِينَ","en":"And even if We had revealed it to one among the foreigners1","tr":"Walaw nazzalnahu AAala baAAdial-aAAjameen","juz":19,"page":375},{"s":26,"a":199,"key":"26:199","ar":"فَقَرَأَهُۥ عَلَيْهِم مَّا كَانُوا۟ بِهِۦ مُؤْمِنِينَ","en":"And he had recited it to them [perfectly],1 they would [still] not have been believers in it.","tr":"Faqaraahu AAalayhim ma kanoobihi mu/mineen","juz":19,"page":375},{"s":26,"a":200,"key":"26:200","ar":"كَذَٰلِكَ سَلَكْنَـٰهُ فِى قُلُوبِ ٱلْمُجْرِمِينَ","en":"Thus have We inserted it [i.e., disbelief] into the hearts of the criminals.","tr":"Kathalika salaknahu feequloobi almujrimeen","juz":19,"page":375},{"s":26,"a":201,"key":"26:201","ar":"لَا يُؤْمِنُونَ بِهِۦ حَتَّىٰ يَرَوُا۟ ٱلْعَذَابَ ٱلْأَلِيمَ","en":"They will not believe in it until they see the painful punishment.","tr":"La yu/minoona bihi hattayarawoo alAAathaba al-aleem","juz":19,"page":375},{"s":26,"a":202,"key":"26:202","ar":"فَيَأْتِيَهُم بَغْتَةً وَهُمْ لَا يَشْعُرُونَ","en":"And it will come to them suddenly while they perceive [it] not.","tr":"Faya/tiyahum baghtatan wahum layashAAuroon","juz":19,"page":375},{"s":26,"a":203,"key":"26:203","ar":"فَيَقُولُوا۟ هَلْ نَحْنُ مُنظَرُونَ","en":"And they will say, \"May we be reprieved?\"","tr":"Fayaqooloo hal nahnu muntharoon","juz":19,"page":375},{"s":26,"a":204,"key":"26:204","ar":"أَفَبِعَذَابِنَا يَسْتَعْجِلُونَ","en":"So for Our punishment are they impatient?","tr":"AfabiAAathabina yastaAAjiloon","juz":19,"page":375},{"s":26,"a":205,"key":"26:205","ar":"أَفَرَءَيْتَ إِن مَّتَّعْنَـٰهُمْ سِنِينَ","en":"Then have you considered if We gave them enjoyment for years","tr":"Afaraayta in mattaAAnahum sineen","juz":19,"page":375},{"s":26,"a":206,"key":"26:206","ar":"ثُمَّ جَآءَهُم مَّا كَانُوا۟ يُوعَدُونَ","en":"And then there came to them that which they were promised?","tr":"Thumma jaahum ma kanooyooAAadoon","juz":19,"page":375},{"s":26,"a":207,"key":"26:207","ar":"مَآ أَغْنَىٰ عَنْهُم مَّا كَانُوا۟ يُمَتَّعُونَ","en":"They would not be availed by the enjoyment with which they were provided.","tr":"Ma aghna AAanhum ma kanooyumattaAAoon","juz":19,"page":376},{"s":26,"a":208,"key":"26:208","ar":"وَمَآ أَهْلَكْنَا مِن قَرْيَةٍ إِلَّا لَهَا مُنذِرُونَ","en":"And We did not destroy any city except that it had warners","tr":"Wama ahlakna min qaryatin illalaha munthiroon","juz":19,"page":376},{"s":26,"a":209,"key":"26:209","ar":"ذِكْرَىٰ وَمَا كُنَّا ظَـٰلِمِينَ","en":"As a reminder; and never have We been unjust.","tr":"Thikra wama kunnathalimeen","juz":19,"page":376},{"s":26,"a":210,"key":"26:210","ar":"وَمَا تَنَزَّلَتْ بِهِ ٱلشَّيَـٰطِينُ","en":"And the devils have not brought it [i.e., the revelation] down.1","tr":"Wama tanazzalat bihi ashshayateen","juz":19,"page":376},{"s":26,"a":211,"key":"26:211","ar":"وَمَا يَنۢبَغِى لَهُمْ وَمَا يَسْتَطِيعُونَ","en":"It is not allowable for them, nor would they be able.","tr":"Wama yanbaghee lahum wamayastateeAAoon","juz":19,"page":376},{"s":26,"a":212,"key":"26:212","ar":"إِنَّهُمْ عَنِ ٱلسَّمْعِ لَمَعْزُولُونَ","en":"Indeed they, from [its] hearing, are removed.1","tr":"Innahum AAani assamAAilamaAAzooloona","juz":19,"page":376},{"s":26,"a":213,"key":"26:213","ar":"فَلَا تَدْعُ مَعَ ٱللَّهِ إِلَـٰهًا ءَاخَرَ فَتَكُونَ مِنَ ٱلْمُعَذَّبِينَ","en":"So do not invoke1 with Allāh another deity and [thus] be among the punished.","tr":"Fala tadAAu maAAa Allahi ilahanakhara fatakoona mina almuAAaththabeen","juz":19,"page":376},{"s":26,"a":214,"key":"26:214","ar":"وَأَنذِرْ عَشِيرَتَكَ ٱلْأَقْرَبِينَ","en":"And warn, [O Muḥammad], your closest kindred.","tr":"Waanthir AAasheerataka al-aqrabeen","juz":19,"page":376},{"s":26,"a":215,"key":"26:215","ar":"وَٱخْفِضْ جَنَاحَكَ لِمَنِ ٱتَّبَعَكَ مِنَ ٱلْمُؤْمِنِينَ","en":"And lower your wing [i.e., show kindness] to those who follow you of the believers.","tr":"Wakhfid janahakalimani ittabaAAaka mina almu/mineen","juz":19,"page":376},{"s":26,"a":216,"key":"26:216","ar":"فَإِنْ عَصَوْكَ فَقُلْ إِنِّى بَرِىٓءٌ مِّمَّا تَعْمَلُونَ","en":"And if they disobey you, then say, \"Indeed, I am disassociated from what you are doing.\"","tr":"Fa-in AAasawka faqul innee baree-onmimma taAAmaloon","juz":19,"page":376},{"s":26,"a":217,"key":"26:217","ar":"وَتَوَكَّلْ عَلَى ٱلْعَزِيزِ ٱلرَّحِيمِ","en":"And rely upon the Exalted in Might, the Merciful,","tr":"Watawakkal AAala alAAazeezi arraheem","juz":19,"page":376},{"s":26,"a":218,"key":"26:218","ar":"ٱلَّذِى يَرَىٰكَ حِينَ تَقُومُ","en":"Who sees you when you arise1","tr":"Allathee yaraka heenataqoom","juz":19,"page":376},{"s":26,"a":219,"key":"26:219","ar":"وَتَقَلُّبَكَ فِى ٱلسَّـٰجِدِينَ","en":"And your movement among those who prostrate.1","tr":"Wataqallubaka fee assajideen","juz":19,"page":376},{"s":26,"a":220,"key":"26:220","ar":"إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"Indeed, He is the Hearing, the Knowing.","tr":"Innahu huwa assameeAAu alAAaleem","juz":19,"page":376},{"s":26,"a":221,"key":"26:221","ar":"هَلْ أُنَبِّئُكُمْ عَلَىٰ مَن تَنَزَّلُ ٱلشَّيَـٰطِينُ","en":"Shall I inform you upon whom the devils descend?","tr":"Hal onabbi-okum AAala man tanazzaluashshayateen","juz":19,"page":376},{"s":26,"a":222,"key":"26:222","ar":"تَنَزَّلُ عَلَىٰ كُلِّ أَفَّاكٍ أَثِيمٍ","en":"They descend upon every sinful liar.","tr":"Tanazzalu AAala kulli affakinatheem","juz":19,"page":376},{"s":26,"a":223,"key":"26:223","ar":"يُلْقُونَ ٱلسَّمْعَ وَأَكْثَرُهُمْ كَـٰذِبُونَ","en":"They pass on what is heard,1 and most of them are liars.","tr":"Yulqoona assamAAa waaktharuhum kathiboon","juz":19,"page":376},{"s":26,"a":224,"key":"26:224","ar":"وَٱلشُّعَرَآءُ يَتَّبِعُهُمُ ٱلْغَاوُۥنَ","en":"And the poets - [only] the deviators follow them;","tr":"WashshuAAaraoyattabiAAuhumu alghawoon","juz":19,"page":376},{"s":26,"a":225,"key":"26:225","ar":"أَلَمْ تَرَ أَنَّهُمْ فِى كُلِّ وَادٍ يَهِيمُونَ","en":"Do you not see that in every valley they roam1","tr":"Alam tara annahum fee kulli wadinyaheemoon","juz":19,"page":376},{"s":26,"a":226,"key":"26:226","ar":"وَأَنَّهُمْ يَقُولُونَ مَا لَا يَفْعَلُونَ","en":"And that they say what they do not do? -","tr":"Waannahum yaqooloona ma layafAAaloon","juz":19,"page":376},{"s":26,"a":227,"key":"26:227","ar":"إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ وَذَكَرُوا۟ ٱللَّهَ كَثِيرًا وَٱنتَصَرُوا۟ مِنۢ بَعْدِ مَا ظُلِمُوا۟ ۗ وَسَيَعْلَمُ ٱلَّذِينَ ظَلَمُوٓا۟ أَىَّ مُنقَلَبٍ يَنقَلِبُونَ","en":"Except those [poets] who believe and do righteous deeds and remember Allāh often and defend [the Muslims]1 after they were wronged. And those who have wronged are going to know to what [kind of] return they will be returned.","tr":"Illa allatheena amanoowaAAamiloo assalihati wathakaroo Allahakatheeran wantasaroo min baAAdi ma thulimoowasayaAAlamu allatheena thalamoo ayyamunqalabin yanqaliboon","juz":19,"page":376},{"s":27,"a":1,"key":"27:1","ar":" طسٓ ۚ تِلْكَ ءَايَـٰتُ ٱلْقُرْءَانِ وَكِتَابٍ مُّبِينٍ","en":"Ṭā, Seen.1 These are the verses of the Qur’ān [i.e., recitation] and a clear Book","tr":"Ta-seen tilka ayatualqur-ani wakitabin mubeen","juz":19,"page":377},{"s":27,"a":2,"key":"27:2","ar":"هُدًى وَبُشْرَىٰ لِلْمُؤْمِنِينَ","en":"As guidance and good tidings for the believers","tr":"Hudan wabushra lilmu/mineen","juz":19,"page":377},{"s":27,"a":3,"key":"27:3","ar":"ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَهُم بِٱلْـَٔاخِرَةِ هُمْ يُوقِنُونَ","en":"Who establish prayer and give zakāh, and of the Hereafter they are certain [in faith].","tr":"Allatheena yuqeemoona assalatawayu/toona azzakata wahum bil-akhiratihum yooqinoon","juz":19,"page":377},{"s":27,"a":4,"key":"27:4","ar":"إِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ زَيَّنَّا لَهُمْ أَعْمَـٰلَهُمْ فَهُمْ يَعْمَهُونَ","en":"Indeed, for those who do not believe in the Hereafter, We have made pleasing to them their deeds, so they wander blindly.","tr":"Inna allatheena la yu/minoonabil-akhirati zayyanna lahum aAAmalahumfahum yaAAmahoon","juz":19,"page":377},{"s":27,"a":5,"key":"27:5","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ لَهُمْ سُوٓءُ ٱلْعَذَابِ وَهُمْ فِى ٱلْـَٔاخِرَةِ هُمُ ٱلْأَخْسَرُونَ","en":"Those are the ones for whom there will be the worst of punishment, and in the Hereafter they are the greatest losers.","tr":"Ola-ika allatheena lahum soo-oalAAathabi wahum fee al-akhirati humu al-akhsaroon","juz":19,"page":377},{"s":27,"a":6,"key":"27:6","ar":"وَإِنَّكَ لَتُلَقَّى ٱلْقُرْءَانَ مِن لَّدُنْ حَكِيمٍ عَلِيمٍ","en":"And indeed, [O Muḥammad], you receive the Qur’ān from one Wise and Knowing.","tr":"Wa-innaka latulaqqa alqur-anamin ladun hakeemin AAaleem","juz":19,"page":377},{"s":27,"a":7,"key":"27:7","ar":"إِذْ قَالَ مُوسَىٰ لِأَهْلِهِۦٓ إِنِّىٓ ءَانَسْتُ نَارًا سَـَٔاتِيكُم مِّنْهَا بِخَبَرٍ أَوْ ءَاتِيكُم بِشِهَابٍ قَبَسٍ لَّعَلَّكُمْ تَصْطَلُونَ","en":"[Mention] when Moses said to his family, \"Indeed, I have perceived a fire. I will bring you from there information or will bring you a burning torch that you may warm yourselves.\"","tr":"Ith qala moosa li-ahlihiinnee anastu naran saateekum minhabikhabarin aw ateekum bishihabin qabasinlaAAallakum tastaloon","juz":19,"page":377},{"s":27,"a":8,"key":"27:8","ar":"فَلَمَّا جَآءَهَا نُودِىَ أَنۢ بُورِكَ مَن فِى ٱلنَّارِ وَمَنْ حَوْلَهَا وَسُبْحَـٰنَ ٱللَّهِ رَبِّ ٱلْعَـٰلَمِينَ","en":"But when he came to it, he was called, \"Blessed is whoever is at the fire and whoever is around it. And exalted is Allāh, Lord of the worlds.","tr":"Falamma jaaha noodiya anboorika man fee annari waman hawlahawasubhana Allahi rabbi alAAalameen","juz":19,"page":377},{"s":27,"a":9,"key":"27:9","ar":"يَـٰمُوسَىٰٓ إِنَّهُۥٓ أَنَا ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"O Moses, indeed it is I - Allāh, the Exalted in Might, the Wise.\"","tr":"Ya moosa innahu ana AllahualAAazeezu alhakeem","juz":19,"page":377},{"s":27,"a":10,"key":"27:10","ar":"وَأَلْقِ عَصَاكَ ۚ فَلَمَّا رَءَاهَا تَهْتَزُّ كَأَنَّهَا جَآنٌّ وَلَّىٰ مُدْبِرًا وَلَمْ يُعَقِّبْ ۚ يَـٰمُوسَىٰ لَا تَخَفْ إِنِّى لَا يَخَافُ لَدَىَّ ٱلْمُرْسَلُونَ","en":"And [he was told], \"Throw down your staff.\" But when he saw it writhing as if it were a snake, he turned in flight and did not return.1 [Allāh said], \"O Moses, fear not. Indeed, in My presence the messengers do not fear.","tr":"Waalqi AAasaka falamma raahatahtazzu kaannaha jannun walla mudbiranwalam yuAAaqqib ya moosa la takhaf innee layakhafu ladayya almursaloon","juz":19,"page":377},{"s":27,"a":11,"key":"27:11","ar":"إِلَّا مَن ظَلَمَ ثُمَّ بَدَّلَ حُسْنًۢا بَعْدَ سُوٓءٍ فَإِنِّى غَفُورٌ رَّحِيمٌ","en":"Otherwise, he who wrongs, then substitutes good after evil - indeed, I am Forgiving and Merciful.","tr":"Illa man thalama thummabaddala husnan baAAda soo-in fa-innee ghafoorun raheem","juz":19,"page":377},{"s":27,"a":12,"key":"27:12","ar":"وَأَدْخِلْ يَدَكَ فِى جَيْبِكَ تَخْرُجْ بَيْضَآءَ مِنْ غَيْرِ سُوٓءٍ ۖ فِى تِسْعِ ءَايَـٰتٍ إِلَىٰ فِرْعَوْنَ وَقَوْمِهِۦٓ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًا فَـٰسِقِينَ","en":"And put your hand into the opening of your garment [at the breast]; it will come out white without disease. [These are] among the nine signs [you will take] to Pharaoh and his people. Indeed, they have been a people defiantly disobedient.\"","tr":"Waadkhil yadaka fee jaybika takhruj baydaamin ghayri soo-in fee tisAAi ayatin ilafirAAawna waqawmihi innahum kanoo qawman fasiqeen","juz":19,"page":377},{"s":27,"a":13,"key":"27:13","ar":"فَلَمَّا جَآءَتْهُمْ ءَايَـٰتُنَا مُبْصِرَةً قَالُوا۟ هَـٰذَا سِحْرٌ مُّبِينٌ","en":"But when there came to them Our visible signs, they said, \"This is obvious magic.\"","tr":"Falamma jaat-hum ayatunamubsiratan qaloo hatha sihrun mubeen","juz":19,"page":377},{"s":27,"a":14,"key":"27:14","ar":"وَجَحَدُوا۟ بِهَا وَٱسْتَيْقَنَتْهَآ أَنفُسُهُمْ ظُلْمًا وَعُلُوًّا ۚ فَٱنظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُفْسِدِينَ","en":"And they rejected them, while their [inner] selves were convinced thereof, out of injustice and haughtiness. So see how was the end of the corrupters.","tr":"Wajahadoo biha wastayqanat-haanfusuhum thulman waAAuluwwan fanthurkayfa kana AAaqibatu almufsideen","juz":19,"page":378},{"s":27,"a":15,"key":"27:15","ar":"وَلَقَدْ ءَاتَيْنَا دَاوُۥدَ وَسُلَيْمَـٰنَ عِلْمًا ۖ وَقَالَا ٱلْحَمْدُ لِلَّهِ ٱلَّذِى فَضَّلَنَا عَلَىٰ كَثِيرٍ مِّنْ عِبَادِهِ ٱلْمُؤْمِنِينَ","en":"And We had certainly given to David and Solomon knowledge, and they said, \"Praise [is due] to Allāh, who has favored us over many of His believing servants.\"","tr":"Walaqad atayna dawoodawasulaymana AAilman waqala alhamdulillahi allathee faddalana AAalakatheerin min AAibadihi almu/mineen","juz":19,"page":378},{"s":27,"a":16,"key":"27:16","ar":"وَوَرِثَ سُلَيْمَـٰنُ دَاوُۥدَ ۖ وَقَالَ يَـٰٓأَيُّهَا ٱلنَّاسُ عُلِّمْنَا مَنطِقَ ٱلطَّيْرِ وَأُوتِينَا مِن كُلِّ شَىْءٍ ۖ إِنَّ هَـٰذَا لَهُوَ ٱلْفَضْلُ ٱلْمُبِينُ","en":"And Solomon inherited David. He said, \"O people, we have been taught the language of birds, and we have been given from all things. Indeed, this is evident bounty.\"","tr":"Wawaritha sulaymanu dawoodawaqala ya ayyuha annasuAAullimna mantiqa attayri waooteenamin kulli shay-in inna hatha lahuwa alfadlualmubeen","juz":19,"page":378},{"s":27,"a":17,"key":"27:17","ar":"وَحُشِرَ لِسُلَيْمَـٰنَ جُنُودُهُۥ مِنَ ٱلْجِنِّ وَٱلْإِنسِ وَٱلطَّيْرِ فَهُمْ يُوزَعُونَ","en":"And gathered for Solomon were his soldiers of the jinn and men and birds, and they were [marching] in rows","tr":"Wahushira lisulaymanajunooduhu mina aljinni wal-insi wattayrifahum yoozaAAoon","juz":19,"page":378},{"s":27,"a":18,"key":"27:18","ar":"حَتَّىٰٓ إِذَآ أَتَوْا۟ عَلَىٰ وَادِ ٱلنَّمْلِ قَالَتْ نَمْلَةٌ يَـٰٓأَيُّهَا ٱلنَّمْلُ ٱدْخُلُوا۟ مَسَـٰكِنَكُمْ لَا يَحْطِمَنَّكُمْ سُلَيْمَـٰنُ وَجُنُودُهُۥ وَهُمْ لَا يَشْعُرُونَ","en":"Until, when they came upon the valley of the ants, an ant said, \"O ants, enter your dwellings that you not be crushed by Solomon and his soldiers while they perceive not.\"","tr":"Hatta itha ataw AAalawadi annamli qalat namlatun ya ayyuhaannamlu odkhuloo masakinakum la yahtimannakumsulaymanu wajunooduhu wahum la yashAAuroon","juz":19,"page":378},{"s":27,"a":19,"key":"27:19","ar":"فَتَبَسَّمَ ضَاحِكًا مِّن قَوْلِهَا وَقَالَ رَبِّ أَوْزِعْنِىٓ أَنْ أَشْكُرَ نِعْمَتَكَ ٱلَّتِىٓ أَنْعَمْتَ عَلَىَّ وَعَلَىٰ وَٰلِدَىَّ وَأَنْ أَعْمَلَ صَـٰلِحًا تَرْضَىٰهُ وَأَدْخِلْنِى بِرَحْمَتِكَ فِى عِبَادِكَ ٱلصَّـٰلِحِينَ","en":"So [Solomon] smiled, amused at her speech, and said, \"My Lord, enable me1 to be grateful for Your favor which You have bestowed upon me and upon my parents and to do righteousness of which You approve. And admit me by Your mercy into [the ranks of] Your righteous servants.\"2","tr":"Fatabassama dahikan min qawlihawaqala rabbi awziAAnee an ashkura niAAmataka allateeanAAamta AAalayya waAAala walidayya waan aAAmala salihantardahu waadkhilnee birahmatika fee AAibadikaassaliheen","juz":19,"page":378},{"s":27,"a":20,"key":"27:20","ar":"وَتَفَقَّدَ ٱلطَّيْرَ فَقَالَ مَا لِىَ لَآ أَرَى ٱلْهُدْهُدَ أَمْ كَانَ مِنَ ٱلْغَآئِبِينَ","en":"And he took attendance of the birds and said, \"Why do I not see the hoopoe - or is he among the absent?","tr":"Watafaqqada attayra faqalama liya la ara alhudhuda am kana minaalgha-ibeen","juz":19,"page":378},{"s":27,"a":21,"key":"27:21","ar":"لَأُعَذِّبَنَّهُۥ عَذَابًا شَدِيدًا أَوْ لَأَا۟ذْبَحَنَّهُۥٓ أَوْ لَيَأْتِيَنِّى بِسُلْطَـٰنٍ مُّبِينٍ","en":"I will surely punish him with a severe punishment or slaughter him unless he brings me clear authorization.\"1","tr":"LaoAAaththibannahu AAathabanshadeedan aw laathbahannahu aw laya/tiyannee bisultaninmubeen","juz":19,"page":378},{"s":27,"a":22,"key":"27:22","ar":"فَمَكَثَ غَيْرَ بَعِيدٍ فَقَالَ أَحَطتُ بِمَا لَمْ تُحِطْ بِهِۦ وَجِئْتُكَ مِن سَبَإٍۭ بِنَبَإٍ يَقِينٍ","en":"But he [i.e., the hoopoe] stayed not long and said, \"I have encompassed [in knowledge] that which you have not encompassed, and I have come to you from Sheba with certain news.","tr":"Famakatha ghayra baAAeedin faqala ahattubima lam tuhit bihi waji/tuka min saba-inbinaba-in yaqeen","juz":19,"page":378},{"s":27,"a":23,"key":"27:23","ar":"إِنِّى وَجَدتُّ ٱمْرَأَةً تَمْلِكُهُمْ وَأُوتِيَتْ مِن كُلِّ شَىْءٍ وَلَهَا عَرْشٌ عَظِيمٌ","en":"Indeed, I found [there] a woman ruling them, and she has been given of all things, and she has a great throne.","tr":"Innee wajadtu imraatan tamlikuhum waootiyatmin kulli shay-in walaha AAarshun AAatheem","juz":19,"page":379},{"s":27,"a":24,"key":"27:24","ar":"وَجَدتُّهَا وَقَوْمَهَا يَسْجُدُونَ لِلشَّمْسِ مِن دُونِ ٱللَّهِ وَزَيَّنَ لَهُمُ ٱلشَّيْطَـٰنُ أَعْمَـٰلَهُمْ فَصَدَّهُمْ عَنِ ٱلسَّبِيلِ فَهُمْ لَا يَهْتَدُونَ","en":"I found her and her people prostrating to the sun instead of Allāh, and Satan has made their deeds pleasing to them and averted them from [His] way, so they are not guided,","tr":"Wajadtuha waqawmaha yasjudoonalishshamsi min dooni Allahi wazayyana lahumu ashshaytanuaAAmalahum fasaddahum AAani assabeeli fahumla yahtadoon","juz":19,"page":379},{"s":27,"a":25,"key":"27:25","ar":"أَلَّا يَسْجُدُوا۟ لِلَّهِ ٱلَّذِى يُخْرِجُ ٱلْخَبْءَ فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَيَعْلَمُ مَا تُخْفُونَ وَمَا تُعْلِنُونَ","en":"[And] so they do not prostrate to Allāh, who brings forth what is hidden within the heavens and the earth and knows what you conceal and what you declare -","tr":"Alla yasjudoo lillahi allatheeyukhriju alkhabaa fee assamawati wal-ardiwayaAAlamu ma tukhfoona wama tuAAlinoon","juz":19,"page":379},{"s":27,"a":26,"key":"27:26","ar":"ٱللَّهُ لَآ إِلَـٰهَ إِلَّا هُوَ رَبُّ ٱلْعَرْشِ ٱلْعَظِيمِ ۩","en":"Allāh - there is no deity except Him, Lord of the Great Throne.\"","tr":"Allahu la ilaha illahuwa rabbu alAAarshi alAAatheem","juz":19,"page":379},{"s":27,"a":27,"key":"27:27","ar":"۞ قَالَ سَنَنظُرُ أَصَدَقْتَ أَمْ كُنتَ مِنَ ٱلْكَـٰذِبِينَ","en":"[Solomon] said, \"We will see whether you were truthful or were of the liars.","tr":"Qala sananthuru asadaqtaam kunta mina alkathibeen","juz":19,"page":379},{"s":27,"a":28,"key":"27:28","ar":"ٱذْهَب بِّكِتَـٰبِى هَـٰذَا فَأَلْقِهْ إِلَيْهِمْ ثُمَّ تَوَلَّ عَنْهُمْ فَٱنظُرْ مَاذَا يَرْجِعُونَ","en":"Take this letter of mine and deliver it to them. Then leave them and see what [answer] they will return.\"","tr":"Ithhab bikitabee hathafaalqih ilayhim thumma tawalla AAanhum fanthurmatha yarjiAAoon","juz":19,"page":379},{"s":27,"a":29,"key":"27:29","ar":"قَالَتْ يَـٰٓأَيُّهَا ٱلْمَلَؤُا۟ إِنِّىٓ أُلْقِىَ إِلَىَّ كِتَـٰبٌ كَرِيمٌ","en":"She said, \"O eminent ones, indeed, to me has been delivered a noble letter.","tr":"Qalat ya ayyuha almalaoinnee olqiya ilayya kitabun kareem","juz":19,"page":379},{"s":27,"a":30,"key":"27:30","ar":"إِنَّهُۥ مِن سُلَيْمَـٰنَ وَإِنَّهُۥ بِسْمِ ٱللَّهِ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ","en":"Indeed, it is from Solomon, and indeed, it is [i.e., reads]: 'In the name of Allāh, the Entirely Merciful, the Especially Merciful,","tr":"Innahu min sulaymana wa-innahu bismiAllahi arrahmani arraheem","juz":19,"page":379},{"s":27,"a":31,"key":"27:31","ar":"أَلَّا تَعْلُوا۟ عَلَىَّ وَأْتُونِى مُسْلِمِينَ","en":"Be not haughty with me but come to me in submission [as Muslims].'\"","tr":"Alla taAAloo AAalayya wa/tooneemuslimeen","juz":19,"page":379},{"s":27,"a":32,"key":"27:32","ar":"قَالَتْ يَـٰٓأَيُّهَا ٱلْمَلَؤُا۟ أَفْتُونِى فِىٓ أَمْرِى مَا كُنتُ قَاطِعَةً أَمْرًا حَتَّىٰ تَشْهَدُونِ","en":"She said, \"O eminent ones, advise me in my affair. I would not decide a matter until you witness [for] me.\"1","tr":"Qalat ya ayyuha almalaoaftoonee fee amree ma kuntu qatiAAatan amran hattatashhadoon","juz":19,"page":379},{"s":27,"a":33,"key":"27:33","ar":"قَالُوا۟ نَحْنُ أُو۟لُوا۟ قُوَّةٍ وَأُو۟لُوا۟ بَأْسٍ شَدِيدٍ وَٱلْأَمْرُ إِلَيْكِ فَٱنظُرِى مَاذَا تَأْمُرِينَ","en":"They said, \"We are men of strength and of great military might, but the command is yours, so see what you will command.\"","tr":"Qaloo nahnu oloo quwwatinwaoloo ba/sin shadeedin wal-amru ilayki fanthureematha ta/mureen","juz":19,"page":379},{"s":27,"a":34,"key":"27:34","ar":"قَالَتْ إِنَّ ٱلْمُلُوكَ إِذَا دَخَلُوا۟ قَرْيَةً أَفْسَدُوهَا وَجَعَلُوٓا۟ أَعِزَّةَ أَهْلِهَآ أَذِلَّةً ۖ وَكَذَٰلِكَ يَفْعَلُونَ","en":"She said, \"Indeed kings - when they enter a city, they ruin it and render the honored of its people humbled. And thus do they do.","tr":"Qalat inna almulooka ithadakhaloo qaryatan afsadooha wajaAAaloo aAAizzata ahlihaathillatan wakathalika yafAAaloon","juz":19,"page":379},{"s":27,"a":35,"key":"27:35","ar":"وَإِنِّى مُرْسِلَةٌ إِلَيْهِم بِهَدِيَّةٍ فَنَاظِرَةٌۢ بِمَ يَرْجِعُ ٱلْمُرْسَلُونَ","en":"But indeed, I will send to them a gift and see with what [reply] the messengers will return.\"","tr":"Wa-innee mursilatun ilayhim bihadiyyatin fanathiratunbima yarjiAAu almursaloon","juz":19,"page":379},{"s":27,"a":36,"key":"27:36","ar":"فَلَمَّا جَآءَ سُلَيْمَـٰنَ قَالَ أَتُمِدُّونَنِ بِمَالٍ فَمَآ ءَاتَىٰنِۦَ ٱللَّهُ خَيْرٌ مِّمَّآ ءَاتَىٰكُم بَلْ أَنتُم بِهَدِيَّتِكُمْ تَفْرَحُونَ","en":"So when they came to Solomon, he said, \"Do you provide me with wealth? But what Allāh has given me is better than what He has given you. Rather, it is you who rejoice in your gift.","tr":"Falamma jaa sulaymana qalaatumiddoonani bimalin fama ataniyaAllahu khayrun mimma atakum bal antumbihadiyyatikum tafrahoon","juz":19,"page":380},{"s":27,"a":37,"key":"27:37","ar":"ٱرْجِعْ إِلَيْهِمْ فَلَنَأْتِيَنَّهُم بِجُنُودٍ لَّا قِبَلَ لَهُم بِهَا وَلَنُخْرِجَنَّهُم مِّنْهَآ أَذِلَّةً وَهُمْ صَـٰغِرُونَ","en":"Return to them, for we will surely come to them with soldiers that they will be powerless to encounter, and we will surely expel them therefrom in humiliation, and they will be debased.\"","tr":"IrjiAA ilayhim falana/tiyannahum bijunoodinla qibala lahum biha walanukhrijannahum minhaathillatan wahum saghiroon","juz":19,"page":380},{"s":27,"a":38,"key":"27:38","ar":"قَالَ يَـٰٓأَيُّهَا ٱلْمَلَؤُا۟ أَيُّكُمْ يَأْتِينِى بِعَرْشِهَا قَبْلَ أَن يَأْتُونِى مُسْلِمِينَ","en":"[Solomon] said, \"O assembly [of jinn], which of you will bring me her throne before they come to me in submission?\"","tr":"Qala ya ayyuha almalaoayyukum ya/teenee biAAarshiha qabla an ya/toonee muslimeen","juz":19,"page":380},{"s":27,"a":39,"key":"27:39","ar":"قَالَ عِفْرِيتٌ مِّنَ ٱلْجِنِّ أَنَا۠ ءَاتِيكَ بِهِۦ قَبْلَ أَن تَقُومَ مِن مَّقَامِكَ ۖ وَإِنِّى عَلَيْهِ لَقَوِىٌّ أَمِينٌ","en":"A powerful one from among the jinn said, \"I will bring it to you before you rise from your place, and indeed, I am for this [task] strong and trustworthy.\"","tr":"Qala AAifreetun mina aljinni anaateeka bihi qabla an taqooma min maqamika wa-inneAAalayhi laqawiyyun ameen","juz":19,"page":380},{"s":27,"a":40,"key":"27:40","ar":"قَالَ ٱلَّذِى عِندَهُۥ عِلْمٌ مِّنَ ٱلْكِتَـٰبِ أَنَا۠ ءَاتِيكَ بِهِۦ قَبْلَ أَن يَرْتَدَّ إِلَيْكَ طَرْفُكَ ۚ فَلَمَّا رَءَاهُ مُسْتَقِرًّا عِندَهُۥ قَالَ هَـٰذَا مِن فَضْلِ رَبِّى لِيَبْلُوَنِىٓ ءَأَشْكُرُ أَمْ أَكْفُرُ ۖ وَمَن شَكَرَ فَإِنَّمَا يَشْكُرُ لِنَفْسِهِۦ ۖ وَمَن كَفَرَ فَإِنَّ رَبِّى غَنِىٌّ كَرِيمٌ","en":"Said one who had knowledge from the Scripture, \"I will bring it to you before your glance returns to you.\" And when [Solomon] saw it placed before him, he said, \"This is from the favor of my Lord to test me whether I will be grateful or ungrateful. And whoever is grateful - his gratitude is only for [the benefit of] himself. And whoever is ungrateful - then indeed, my Lord is Free of need and Generous.\"","tr":"Qala allathee AAindahu AAilmunmina alkitabi ana ateeka bihi qabla anyartadda ilayka tarfuka falamma raahumustaqirran AAindahu qala hatha min fadlirabbee liyabluwanee aashkuru am akfuru waman shakara fa-innamayashkuru linafsihi waman kafara fa-inna rabbee ghaniyyun kareem","juz":19,"page":380},{"s":27,"a":41,"key":"27:41","ar":"قَالَ نَكِّرُوا۟ لَهَا عَرْشَهَا نَنظُرْ أَتَهْتَدِىٓ أَمْ تَكُونُ مِنَ ٱلَّذِينَ لَا يَهْتَدُونَ","en":"He said, \"Disguise for her her throne; we will see whether she will be guided [to truth] or will be of those who is not guided.\"","tr":"Qala nakkiroo laha AAarshahananthur atahtadee am takoonu mina allatheenala yahtadoon","juz":19,"page":380},{"s":27,"a":42,"key":"27:42","ar":"فَلَمَّا جَآءَتْ قِيلَ أَهَـٰكَذَا عَرْشُكِ ۖ قَالَتْ كَأَنَّهُۥ هُوَ ۚ وَأُوتِينَا ٱلْعِلْمَ مِن قَبْلِهَا وَكُنَّا مُسْلِمِينَ","en":"So when she arrived, it was said [to her], \"Is your throne like this?\" She said, \"[It is] as though it was it.\" [Solomon said], \"And we were given knowledge before her, and we have been Muslims [in submission to Allāh].","tr":"Falamma jaat qeela ahakathaAAarshuki qalat kaannahu huwa waooteena alAAilmamin qabliha wakunna muslimeen","juz":19,"page":380},{"s":27,"a":43,"key":"27:43","ar":"وَصَدَّهَا مَا كَانَت تَّعْبُدُ مِن دُونِ ٱللَّهِ ۖ إِنَّهَا كَانَتْ مِن قَوْمٍ كَـٰفِرِينَ","en":"And that which she was worshipping other than Allāh had averted her [from submission to Him]. Indeed, she was from a disbelieving people.\"","tr":"Wasaddaha ma kanattaAAbudu min dooni Allahi innaha kanat minqawmin kafireen","juz":19,"page":380},{"s":27,"a":44,"key":"27:44","ar":"قِيلَ لَهَا ٱدْخُلِى ٱلصَّرْحَ ۖ فَلَمَّا رَأَتْهُ حَسِبَتْهُ لُجَّةً وَكَشَفَتْ عَن سَاقَيْهَا ۚ قَالَ إِنَّهُۥ صَرْحٌ مُّمَرَّدٌ مِّن قَوَارِيرَ ۗ قَالَتْ رَبِّ إِنِّى ظَلَمْتُ نَفْسِى وَأَسْلَمْتُ مَعَ سُلَيْمَـٰنَ لِلَّهِ رَبِّ ٱلْعَـٰلَمِينَ","en":"She was told, \"Enter the palace.\" But when she saw it, she thought it was a body of water1 and uncovered her shins [to wade through]. He said, \"Indeed, it is a palace [whose floor is] made smooth with glass.\" She said, \"My Lord, indeed I have wronged myself, and I submit with Solomon to Allāh, Lord of the worlds.\"","tr":"Qeela laha odkhulee assarhafalamma raat-hu hasibat-hu lujjatan wakashafat AAansaqayha qala innahu sarhunmumarradun min qawareera qalat rabbi innee thalamtunafsee waaslamtu maAAa sulaymana lillahi rabbi alAAalameen","juz":19,"page":380},{"s":27,"a":45,"key":"27:45","ar":"وَلَقَدْ أَرْسَلْنَآ إِلَىٰ ثَمُودَ أَخَاهُمْ صَـٰلِحًا أَنِ ٱعْبُدُوا۟ ٱللَّهَ فَإِذَا هُمْ فَرِيقَانِ يَخْتَصِمُونَ","en":"And We had certainly sent to Thamūd their brother Ṣāliḥ, [saying], \"Worship Allāh,\" and at once they were two parties conflicting.","tr":"Walaqad arsalna ila thamoodaakhahum salihan ani oAAbudoo Allahafa-itha hum fareeqani yakhtasimoon","juz":19,"page":381},{"s":27,"a":46,"key":"27:46","ar":"قَالَ يَـٰقَوْمِ لِمَ تَسْتَعْجِلُونَ بِٱلسَّيِّئَةِ قَبْلَ ٱلْحَسَنَةِ ۖ لَوْلَا تَسْتَغْفِرُونَ ٱللَّهَ لَعَلَّكُمْ تُرْحَمُونَ","en":"He said, \"O my people, why are you impatient for evil before [i.e., instead of] good?1 Why do you not seek forgiveness of Allāh that you may receive mercy?\"","tr":"Qala ya qawmi limatastaAAjiloona bissayyi-ati qabla alhasanati lawlatastaghfiroona Allaha laAAallakum turhamoon","juz":19,"page":381},{"s":27,"a":47,"key":"27:47","ar":"قَالُوا۟ ٱطَّيَّرْنَا بِكَ وَبِمَن مَّعَكَ ۚ قَالَ طَـٰٓئِرُكُمْ عِندَ ٱللَّهِ ۖ بَلْ أَنتُمْ قَوْمٌ تُفْتَنُونَ","en":"They said, \"We consider you a bad omen, you and those with you.\" He said, \"Your omen [i.e., fate] is with Allāh. Rather, you are a people being tested.\"1","tr":"Qaloo ittayyarna bikawabiman maAAaka qala ta-irukum AAinda Allahibal antum qawmun tuftanoon","juz":19,"page":381},{"s":27,"a":48,"key":"27:48","ar":"وَكَانَ فِى ٱلْمَدِينَةِ تِسْعَةُ رَهْطٍ يُفْسِدُونَ فِى ٱلْأَرْضِ وَلَا يُصْلِحُونَ","en":"And there were in the city nine family heads causing corruption in the land and not amending [its affairs].","tr":"Wakana fee almadeenati tisAAatu rahtinyufsidoona fee al-ardi wala yuslihoon","juz":19,"page":381},{"s":27,"a":49,"key":"27:49","ar":"قَالُوا۟ تَقَاسَمُوا۟ بِٱللَّهِ لَنُبَيِّتَنَّهُۥ وَأَهْلَهُۥ ثُمَّ لَنَقُولَنَّ لِوَلِيِّهِۦ مَا شَهِدْنَا مَهْلِكَ أَهْلِهِۦ وَإِنَّا لَصَـٰدِقُونَ","en":"They said, \"Take a mutual oath by Allāh that we will kill him by night, he and his family. Then we will say to his executor,1 'We did not witness the destruction of his family, and indeed, we are truthful.'\"","tr":"Qaloo taqasamoo billahilanubayyitannahu waahlahu thumma lanaqoolanna liwaliyyihi mashahidna mahlika ahlihi wa-inna lasadiqoon","juz":19,"page":381},{"s":27,"a":50,"key":"27:50","ar":"وَمَكَرُوا۟ مَكْرًا وَمَكَرْنَا مَكْرًا وَهُمْ لَا يَشْعُرُونَ","en":"And they planned a plan, and We planned a plan, while they perceived not.","tr":"Wamakaroo makran wamakarna makranwahum la yashAAuroon","juz":19,"page":381},{"s":27,"a":51,"key":"27:51","ar":"فَٱنظُرْ كَيْفَ كَانَ عَـٰقِبَةُ مَكْرِهِمْ أَنَّا دَمَّرْنَـٰهُمْ وَقَوْمَهُمْ أَجْمَعِينَ","en":"Then look how was the outcome of their plan - that We destroyed them and their people, all.","tr":"Fanthur kayfa kanaAAaqibatu makrihim anna dammarnahumwaqawmahum ajmaAAeen","juz":19,"page":381},{"s":27,"a":52,"key":"27:52","ar":"فَتِلْكَ بُيُوتُهُمْ خَاوِيَةًۢ بِمَا ظَلَمُوٓا۟ ۗ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّقَوْمٍ يَعْلَمُونَ","en":"So those are their houses, desolate because of the wrong they had done. Indeed in that is a sign for people who know.","tr":"Fatilka buyootuhum khawiyatan bimathalamoo inna fee thalika laayatanliqawmin yaAAlamoon","juz":19,"page":381},{"s":27,"a":53,"key":"27:53","ar":"وَأَنجَيْنَا ٱلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ","en":"And We saved those who believed and used to fear Allāh.","tr":"Waanjayna allatheena amanoowakanoo yattaqoon","juz":19,"page":381},{"s":27,"a":54,"key":"27:54","ar":"وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ أَتَأْتُونَ ٱلْفَـٰحِشَةَ وَأَنتُمْ تُبْصِرُونَ","en":"And [mention] Lot, when he said to his people, \"Do you commit immorality1 while you are seeing?2","tr":"Walootan ith qalaliqawmihi ata/toona alfahishata waantum tubsiroon","juz":19,"page":381},{"s":27,"a":55,"key":"27:55","ar":"أَئِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ شَهْوَةً مِّن دُونِ ٱلنِّسَآءِ ۚ بَلْ أَنتُمْ قَوْمٌ تَجْهَلُونَ","en":"Do you indeed approach men with desire instead of women? Rather, you are a people behaving ignorantly.\"","tr":"A-innakum lata/toona arrijalashahwatan min dooni annisa-i bal antum qawmuntajhaloon","juz":19,"page":381},{"s":27,"a":56,"key":"27:56","ar":"۞ فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوٓا۟ أَخْرِجُوٓا۟ ءَالَ لُوطٍ مِّن قَرْيَتِكُمْ ۖ إِنَّهُمْ أُنَاسٌ يَتَطَهَّرُونَ","en":"But the answer of his people was not except that they said, \"Expel the family of Lot from your city. Indeed, they are people who keep themselves pure.\"","tr":"Fama kana jawabaqawmihi illa an qaloo akhrijoo ala lootinmin qaryatikum innahum onasun yatatahharoon","juz":20,"page":382},{"s":27,"a":57,"key":"27:57","ar":"فَأَنجَيْنَـٰهُ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ قَدَّرْنَـٰهَا مِنَ ٱلْغَـٰبِرِينَ","en":"So We saved him and his family, except for his wife; We destined her to be of those who remained behind.","tr":"Faanjaynahu waahlahu illaimraatahu qaddarnaha mina alghabireen","juz":20,"page":382},{"s":27,"a":58,"key":"27:58","ar":"وَأَمْطَرْنَا عَلَيْهِم مَّطَرًا ۖ فَسَآءَ مَطَرُ ٱلْمُنذَرِينَ","en":"And We rained upon them a rain [of stones], and evil was the rain of those who were warned.","tr":"Waamtarna AAalayhim mataranfasaa mataru almunthareen","juz":20,"page":382},{"s":27,"a":59,"key":"27:59","ar":"قُلِ ٱلْحَمْدُ لِلَّهِ وَسَلَـٰمٌ عَلَىٰ عِبَادِهِ ٱلَّذِينَ ٱصْطَفَىٰٓ ۗ ءَآللَّهُ خَيْرٌ أَمَّا يُشْرِكُونَ","en":"Say, [O Muḥammad], \"Praise be to Allāh, and peace upon His servants whom He has chosen. Is Allāh better or what they associate with Him?\"","tr":"Quli alhamdu lillahi wasalamunAAala AAibadihi allatheena istafaallahu khayrun amma yushrikoon","juz":20,"page":382},{"s":27,"a":60,"key":"27:60","ar":"أَمَّنْ خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَأَنزَلَ لَكُم مِّنَ ٱلسَّمَآءِ مَآءً فَأَنۢبَتْنَا بِهِۦ حَدَآئِقَ ذَاتَ بَهْجَةٍ مَّا كَانَ لَكُمْ أَن تُنۢبِتُوا۟ شَجَرَهَآ ۗ أَءِلَـٰهٌ مَّعَ ٱللَّهِ ۚ بَلْ هُمْ قَوْمٌ يَعْدِلُونَ","en":"[More precisely], is He [not best] who created the heavens and the earth and sent down for you rain from the sky, causing to grow thereby gardens of joyful beauty which you could not [otherwise] have grown the trees thereof? Is there a deity with Allāh?1 [No], but they are a people who ascribe equals [to Him].","tr":"Amman khalaqa assamawatiwal-arda waanzala lakum mina assama-imaan faanbatna bihi hada-iqa thatabahjatin ma kana lakum an tunbitoo shajarahaa-ilahun maAAa Allahi bal hum qawmun yaAAdiloon","juz":20,"page":382},{"s":27,"a":61,"key":"27:61","ar":"أَمَّن جَعَلَ ٱلْأَرْضَ قَرَارًا وَجَعَلَ خِلَـٰلَهَآ أَنْهَـٰرًا وَجَعَلَ لَهَا رَوَٰسِىَ وَجَعَلَ بَيْنَ ٱلْبَحْرَيْنِ حَاجِزًا ۗ أَءِلَـٰهٌ مَّعَ ٱللَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ","en":"Is He [not best] who made the earth a stable ground and placed within it rivers and made for it firmly set mountains and placed between the two seas a barrier? Is there a deity with Allāh? [No], but most of them do not know.","tr":"Amman jaAAala al-arda qararanwajaAAala khilalaha anharan wajaAAala laharawasiya wajaAAala bayna albahrayni hajizana-ilahun maAAa Allahi bal aktharuhum layaAAlamoon","juz":20,"page":382},{"s":27,"a":62,"key":"27:62","ar":"أَمَّن يُجِيبُ ٱلْمُضْطَرَّ إِذَا دَعَاهُ وَيَكْشِفُ ٱلسُّوٓءَ وَيَجْعَلُكُمْ خُلَفَآءَ ٱلْأَرْضِ ۗ أَءِلَـٰهٌ مَّعَ ٱللَّهِ ۚ قَلِيلًا مَّا تَذَكَّرُونَ","en":"Is He [not best] who responds to the desperate one when he calls upon Him and removes evil and makes you inheritors of the earth?1 Is there a deity with Allāh? Little do you remember.","tr":"Amman yujeebu almudtarra ithadaAAahu wayakshifu assoo-a wayajAAalukum khulafaaal-ardi a-ilahun maAAa Allahi qaleelan matathakkaroon","juz":20,"page":382},{"s":27,"a":63,"key":"27:63","ar":"أَمَّن يَهْدِيكُمْ فِى ظُلُمَـٰتِ ٱلْبَرِّ وَٱلْبَحْرِ وَمَن يُرْسِلُ ٱلرِّيَـٰحَ بُشْرًۢا بَيْنَ يَدَىْ رَحْمَتِهِۦٓ ۗ أَءِلَـٰهٌ مَّعَ ٱللَّهِ ۚ تَعَـٰلَى ٱللَّهُ عَمَّا يُشْرِكُونَ","en":"Is He [not best] who guides you through the darknesses of the land and sea and who sends the winds as good tidings before His mercy? Is there a deity with Allāh? High is Allāh above whatever they associate with Him.","tr":"Amman yahdeekum fee thulumatialbarri walbahri waman yursilu arriyahabushran bayna yaday rahmatihi a-ilahun maAAa AllahitaAAala Allahu AAamma yushrikoon","juz":20,"page":382},{"s":27,"a":64,"key":"27:64","ar":"أَمَّن يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ وَمَن يَرْزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ ۗ أَءِلَـٰهٌ مَّعَ ٱللَّهِ ۚ قُلْ هَاتُوا۟ بُرْهَـٰنَكُمْ إِن كُنتُمْ صَـٰدِقِينَ","en":"Is He [not best] who begins creation and then repeats it and who provides for you from the heaven and earth? Is there a deity with Allāh? Say, \"Produce your proof, if you should be truthful.\"","tr":"Amman yabdao alkhalqa thumma yuAAeeduhuwaman yarzuqukum mina assama-i wal-ardia-ilahun maAAa Allahi qul hatoo burhanakumin kuntum sadiqeen","juz":20,"page":383},{"s":27,"a":65,"key":"27:65","ar":"قُل لَّا يَعْلَمُ مَن فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ٱلْغَيْبَ إِلَّا ٱللَّهُ ۚ وَمَا يَشْعُرُونَ أَيَّانَ يُبْعَثُونَ","en":"Say, \"None in the heavens and earth knows the unseen except Allāh, and they do not perceive when they will be resurrected.\"","tr":"Qul la yaAAlamu man fee assamawatiwal-ardi alghayba illa Allahu wamayashAAuroona ayyana yubAAathoon","juz":20,"page":383},{"s":27,"a":66,"key":"27:66","ar":"بَلِ ٱدَّٰرَكَ عِلْمُهُمْ فِى ٱلْـَٔاخِرَةِ ۚ بَلْ هُمْ فِى شَكٍّ مِّنْهَا ۖ بَلْ هُم مِّنْهَا عَمُونَ","en":"Rather, their knowledge is arrested concerning the Hereafter. Rather, they are in doubt about it. Rather, they are, concerning it, blind.","tr":"Bali iddaraka AAilmuhum fee al-akhiratibal hum fee shakkin minha bal hum minha AAamoon","juz":20,"page":383},{"s":27,"a":67,"key":"27:67","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوٓا۟ أَءِذَا كُنَّا تُرَٰبًا وَءَابَآؤُنَآ أَئِنَّا لَمُخْرَجُونَ","en":"And those who disbelieve say, \"When we have become dust as well as our forefathers, will we indeed be brought out [of the graves]?","tr":"Waqala allatheena kafaroo a-ithakunna turaban waabaona a-innalamukhrajoon","juz":20,"page":383},{"s":27,"a":68,"key":"27:68","ar":"لَقَدْ وُعِدْنَا هَـٰذَا نَحْنُ وَءَابَآؤُنَا مِن قَبْلُ إِنْ هَـٰذَآ إِلَّآ أَسَـٰطِيرُ ٱلْأَوَّلِينَ","en":"We have been promised this, we and our forefathers, before. This is not but legends of the former peoples.\"","tr":"Laqad wuAAidna hatha nahnuwaabaona min qablu in hatha illaasateeru al-awwaleen","juz":20,"page":383},{"s":27,"a":69,"key":"27:69","ar":"قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُجْرِمِينَ","en":"Say, [O Muḥammad], \"Proceed [i.e., travel] through the land and observe how was the end of the criminals.\"","tr":"Qul seeroo fee al-ardi fanthurookayfa kana AAaqibatu almujrimeen","juz":20,"page":383},{"s":27,"a":70,"key":"27:70","ar":"وَلَا تَحْزَنْ عَلَيْهِمْ وَلَا تَكُن فِى ضَيْقٍ مِّمَّا يَمْكُرُونَ","en":"And grieve not over them or be in distress from what they conspire.","tr":"Wala tahzan AAalayhim walatakun fee dayqin mimma yamkuroon","juz":20,"page":383},{"s":27,"a":71,"key":"27:71","ar":"وَيَقُولُونَ مَتَىٰ هَـٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَ","en":"And they say, \"When is [the fulfillment of] this promise, if you should be truthful?\"","tr":"Wayaqooloona mata hathaalwaAAdu in kuntum sadiqeen","juz":20,"page":383},{"s":27,"a":72,"key":"27:72","ar":"قُلْ عَسَىٰٓ أَن يَكُونَ رَدِفَ لَكُم بَعْضُ ٱلَّذِى تَسْتَعْجِلُونَ","en":"Say, \"Perhaps it is close behind you [i.e., very near] - some of that for which you are impatient.","tr":"Qul AAasa an yakoona radifa lakumbaAAdu allathee tastaAAjiloon","juz":20,"page":383},{"s":27,"a":73,"key":"27:73","ar":"وَإِنَّ رَبَّكَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَشْكُرُونَ","en":"And indeed, your Lord is the possessor of bounty for the people, but most of them are not grateful.\"","tr":"Wa-inna rabbaka lathoo fadlinAAala annasi walakinna aktharahum layashkuroon","juz":20,"page":383},{"s":27,"a":74,"key":"27:74","ar":"وَإِنَّ رَبَّكَ لَيَعْلَمُ مَا تُكِنُّ صُدُورُهُمْ وَمَا يُعْلِنُونَ","en":"And indeed, your Lord knows what their breasts conceal and what they declare.","tr":"Wa-inna rabbaka layaAAlamu ma tukinnusudooruhum wama yuAAlinoon","juz":20,"page":383},{"s":27,"a":75,"key":"27:75","ar":"وَمَا مِنْ غَآئِبَةٍ فِى ٱلسَّمَآءِ وَٱلْأَرْضِ إِلَّا فِى كِتَـٰبٍ مُّبِينٍ","en":"And there is nothing concealed1 within the heaven and the earth except that it is in a clear Register.2","tr":"Wama min gha-ibatin fee assama-iwal-ardi illa fee kitabin mubeen","juz":20,"page":383},{"s":27,"a":76,"key":"27:76","ar":"إِنَّ هَـٰذَا ٱلْقُرْءَانَ يَقُصُّ عَلَىٰ بَنِىٓ إِسْرَٰٓءِيلَ أَكْثَرَ ٱلَّذِى هُمْ فِيهِ يَخْتَلِفُونَ","en":"Indeed, this Qur’ān relates to the Children of Israel most of that over which they disagree.","tr":"Inna hatha alqur-ana yaqussuAAala banee isra-eela akthara allathee humfeehi yakhtalifoon","juz":20,"page":383},{"s":27,"a":77,"key":"27:77","ar":"وَإِنَّهُۥ لَهُدًى وَرَحْمَةٌ لِّلْمُؤْمِنِينَ","en":"And indeed, it is guidance and mercy for the believers.","tr":"Wa-innahu lahudan warahmatunlilmu/mineen","juz":20,"page":384},{"s":27,"a":78,"key":"27:78","ar":"إِنَّ رَبَّكَ يَقْضِى بَيْنَهُم بِحُكْمِهِۦ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْعَلِيمُ","en":"Indeed, your Lord will judge between them by His [wise] judgement. And He is the Exalted in Might, the Knowing.","tr":"Inna rabbaka yaqdee baynahum bihukmihiwahuwa alAAazeezu alAAaleem","juz":20,"page":384},{"s":27,"a":79,"key":"27:79","ar":"فَتَوَكَّلْ عَلَى ٱللَّهِ ۖ إِنَّكَ عَلَى ٱلْحَقِّ ٱلْمُبِينِ","en":"So rely upon Allāh; indeed, you are upon the clear truth.","tr":"Fatawakkal AAala Allahi innakaAAala alhaqqi almubeen","juz":20,"page":384},{"s":27,"a":80,"key":"27:80","ar":"إِنَّكَ لَا تُسْمِعُ ٱلْمَوْتَىٰ وَلَا تُسْمِعُ ٱلصُّمَّ ٱلدُّعَآءَ إِذَا وَلَّوْا۟ مُدْبِرِينَ","en":"Indeed, you will not make the dead hear, nor will you make the deaf hear the call when they have turned their backs retreating.","tr":"Innaka la tusmiAAu almawta walatusmiAAu assumma adduAAaa ithawallaw mudbireen","juz":20,"page":384},{"s":27,"a":81,"key":"27:81","ar":"وَمَآ أَنتَ بِهَـٰدِى ٱلْعُمْىِ عَن ضَلَـٰلَتِهِمْ ۖ إِن تُسْمِعُ إِلَّا مَن يُؤْمِنُ بِـَٔايَـٰتِنَا فَهُم مُّسْلِمُونَ","en":"And you cannot guide the blind away from their error. You will only make hear those who believe in Our verses so they are Muslims [i.e., submitting to Allāh].","tr":"Wama anta bihadee alAAumyiAAan dalalatihim in tusmiAAu illa manyu/minu bi-ayatina fahum muslimoon","juz":20,"page":384},{"s":27,"a":82,"key":"27:82","ar":"۞ وَإِذَا وَقَعَ ٱلْقَوْلُ عَلَيْهِمْ أَخْرَجْنَا لَهُمْ دَآبَّةً مِّنَ ٱلْأَرْضِ تُكَلِّمُهُمْ أَنَّ ٱلنَّاسَ كَانُوا۟ بِـَٔايَـٰتِنَا لَا يُوقِنُونَ","en":"And when the word [i.e., decree] befalls them,1 We will bring forth for them a creature from the earth speaking to them, [saying] that the people were, of Our verses, not certain [in faith].","tr":"Wa-itha waqaAAa alqawlu AAalayhimakhrajna lahum dabbatan mina al-arditukallimuhum anna annasa kanoo bi-ayatinala yooqinoon","juz":20,"page":384},{"s":27,"a":83,"key":"27:83","ar":"وَيَوْمَ نَحْشُرُ مِن كُلِّ أُمَّةٍ فَوْجًا مِّمَّن يُكَذِّبُ بِـَٔايَـٰتِنَا فَهُمْ يُوزَعُونَ","en":"And [warn of] the Day when We will gather from every nation a company of those who deny Our signs, and they will be [driven] in rows","tr":"Wayawma nahshuru min kulli ommatinfawjan mimman yukaththibu bi-ayatinafahum yoozaAAoon","juz":20,"page":384},{"s":27,"a":84,"key":"27:84","ar":"حَتَّىٰٓ إِذَا جَآءُو قَالَ أَكَذَّبْتُم بِـَٔايَـٰتِى وَلَمْ تُحِيطُوا۟ بِهَا عِلْمًا أَمَّاذَا كُنتُمْ تَعْمَلُونَ","en":"Until, when they arrive [at the place of Judgement], He will say, \"Did you deny My signs while you encompassed them not in knowledge, or what [was it that] you were doing?\"","tr":"Hatta itha jaooqala akaththabtum bi-ayatee walam tuheetoobiha AAilman ammatha kuntum taAAmaloon","juz":20,"page":384},{"s":27,"a":85,"key":"27:85","ar":"وَوَقَعَ ٱلْقَوْلُ عَلَيْهِم بِمَا ظَلَمُوا۟ فَهُمْ لَا يَنطِقُونَ","en":"And the decree will befall them1 for the wrong they did, and they will not [be able to] speak.","tr":"WawaqaAAa alqawlu AAalayhim bima thalamoofahum la yantiqoon","juz":20,"page":384},{"s":27,"a":86,"key":"27:86","ar":"أَلَمْ يَرَوْا۟ أَنَّا جَعَلْنَا ٱلَّيْلَ لِيَسْكُنُوا۟ فِيهِ وَٱلنَّهَارَ مُبْصِرًا ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يُؤْمِنُونَ","en":"Do they not see that We made the night that they may rest therein and the day giving sight? Indeed in that are signs for a people who believe.","tr":"Alam yaraw anna jaAAalnaallayla liyaskunoo feehi wannahara mubsiraninna fee thalika laayatin liqawmin yu/minoon","juz":20,"page":384},{"s":27,"a":87,"key":"27:87","ar":"وَيَوْمَ يُنفَخُ فِى ٱلصُّورِ فَفَزِعَ مَن فِى ٱلسَّمَـٰوَٰتِ وَمَن فِى ٱلْأَرْضِ إِلَّا مَن شَآءَ ٱللَّهُ ۚ وَكُلٌّ أَتَوْهُ دَٰخِرِينَ","en":"And [warn of] the Day the Horn will be blown, and whoever is in the heavens and whoever is on the earth will be terrified except whom Allāh wills. And all will come to Him humbled.","tr":"Wayawma yunfakhu fee assoorifafaziAAa man fee assamawati waman feeal-ardi illa man shaa Allahu wakullunatawhu dakhireen","juz":20,"page":384},{"s":27,"a":88,"key":"27:88","ar":"وَتَرَى ٱلْجِبَالَ تَحْسَبُهَا جَامِدَةً وَهِىَ تَمُرُّ مَرَّ ٱلسَّحَابِ ۚ صُنْعَ ٱللَّهِ ٱلَّذِىٓ أَتْقَنَ كُلَّ شَىْءٍ ۚ إِنَّهُۥ خَبِيرٌۢ بِمَا تَفْعَلُونَ","en":"And you see the mountains, thinking them motionless,1 while they will pass as the passing of clouds. [It is] the work of Allāh, who perfected all things. Indeed, He is Aware of that which you do.","tr":"Watara aljibala tahsabuhajamidatan wahiya tamurru marra assahabi sunAAaAllahi allathee atqana kulla shay-in innahukhabeerun bima tafAAaloon","juz":20,"page":384},{"s":27,"a":89,"key":"27:89","ar":"مَن جَآءَ بِٱلْحَسَنَةِ فَلَهُۥ خَيْرٌ مِّنْهَا وَهُم مِّن فَزَعٍ يَوْمَئِذٍ ءَامِنُونَ","en":"Whoever comes [at Judgement] with a good deed will have better than it, and they, from the terror of that Day, will be safe.","tr":"Man jaa bilhasanatifalahu khayrun minha wahum min fazaAAin yawma-ithinaminoon","juz":20,"page":385},{"s":27,"a":90,"key":"27:90","ar":"وَمَن جَآءَ بِٱلسَّيِّئَةِ فَكُبَّتْ وُجُوهُهُمْ فِى ٱلنَّارِ هَلْ تُجْزَوْنَ إِلَّا مَا كُنتُمْ تَعْمَلُونَ","en":"And whoever comes with an evil deed1 - their faces will be overturned into the Fire, [and it will be said], \"Are you recompensed except for what you used to do?\"","tr":"Waman jaa bissayyi-atifakubbat wujoohuhum fee annari hal tujzawna illama kuntum taAAmaloon","juz":20,"page":385},{"s":27,"a":91,"key":"27:91","ar":"إِنَّمَآ أُمِرْتُ أَنْ أَعْبُدَ رَبَّ هَـٰذِهِ ٱلْبَلْدَةِ ٱلَّذِى حَرَّمَهَا وَلَهُۥ كُلُّ شَىْءٍ ۖ وَأُمِرْتُ أَنْ أَكُونَ مِنَ ٱلْمُسْلِمِينَ","en":"[Say, O Muḥammad], \"I have only been commanded to worship the Lord of this city,1 who made it sacred and to whom [belongs] all things. And I am commanded to be of the Muslims [i.e., those who submit to Allāh].","tr":"Innama omirtu an aAAbuda rabba hathihialbaldati allathee harramaha walahu kullushay-in waomirtu an akoona mina almuslimeen","juz":20,"page":385},{"s":27,"a":92,"key":"27:92","ar":"وَأَنْ أَتْلُوَا۟ ٱلْقُرْءَانَ ۖ فَمَنِ ٱهْتَدَىٰ فَإِنَّمَا يَهْتَدِى لِنَفْسِهِۦ ۖ وَمَن ضَلَّ فَقُلْ إِنَّمَآ أَنَا۠ مِنَ ٱلْمُنذِرِينَ","en":"And to recite the Qur’ān.\" And whoever is guided is only guided for [the benefit of] himself; and whoever strays - say, \"I am only [one] of the warners.\"","tr":"Waan atluwa alqur-ana famani ihtadafa-innama yahtadee linafsihi waman dalla faqulinnama ana mina almunthireen","juz":20,"page":385},{"s":27,"a":93,"key":"27:93","ar":"وَقُلِ ٱلْحَمْدُ لِلَّهِ سَيُرِيكُمْ ءَايَـٰتِهِۦ فَتَعْرِفُونَهَا ۚ وَمَا رَبُّكَ بِغَـٰفِلٍ عَمَّا تَعْمَلُونَ","en":"And say, \"[All] praise is [due] to Allāh. He will show you His signs, and you will recognize them. And your Lord is not unaware of what you do.\"","tr":"Waquli alhamdu lillahisayureekum ayatihi fataAArifoonaha wamarabbuka bighafilin AAamma taAAmaloon","juz":20,"page":385},{"s":28,"a":1,"key":"28:1","ar":" طسٓمٓ","en":"Ṭā, Seen, Meem.1","tr":"Ta-seen-meem","juz":20,"page":385},{"s":28,"a":2,"key":"28:2","ar":"تِلْكَ ءَايَـٰتُ ٱلْكِتَـٰبِ ٱلْمُبِينِ","en":"These are verses of the clear Book.","tr":"Tilka ayatu alkitabialmubeen","juz":20,"page":385},{"s":28,"a":3,"key":"28:3","ar":"نَتْلُوا۟ عَلَيْكَ مِن نَّبَإِ مُوسَىٰ وَفِرْعَوْنَ بِٱلْحَقِّ لِقَوْمٍ يُؤْمِنُونَ","en":"We recite to you from the news of Moses and Pharaoh in truth for a people who believe.","tr":"Natloo AAalayka min naba-i moosawafirAAawna bilhaqqi liqawmin yu/minoon","juz":20,"page":385},{"s":28,"a":4,"key":"28:4","ar":"إِنَّ فِرْعَوْنَ عَلَا فِى ٱلْأَرْضِ وَجَعَلَ أَهْلَهَا شِيَعًا يَسْتَضْعِفُ طَآئِفَةً مِّنْهُمْ يُذَبِّحُ أَبْنَآءَهُمْ وَيَسْتَحْىِۦ نِسَآءَهُمْ ۚ إِنَّهُۥ كَانَ مِنَ ٱلْمُفْسِدِينَ","en":"Indeed, Pharaoh exalted himself in the land and made its people into factions, oppressing a sector among them, slaughtering their [newborn] sons and keeping their females alive. Indeed, he was of the corrupters.","tr":"Inna firAAawna AAala fee al-ardiwajaAAala ahlaha shiyaAAan yastadAAifu ta-ifatanminhum yuthabbihu abnaahum wayastahyeenisaahum innahu kana mina almufsideen","juz":20,"page":385},{"s":28,"a":5,"key":"28:5","ar":"وَنُرِيدُ أَن نَّمُنَّ عَلَى ٱلَّذِينَ ٱسْتُضْعِفُوا۟ فِى ٱلْأَرْضِ وَنَجْعَلَهُمْ أَئِمَّةً وَنَجْعَلَهُمُ ٱلْوَٰرِثِينَ","en":"And We wanted to confer favor upon those who were oppressed in the land and make them leaders and make them inheritors","tr":"Wanureedu an namunna AAala allatheenaistudAAifoo fee al-ardi wanajAAalahum a-immatanwanajAAalahumu alwaritheen","juz":20,"page":385},{"s":28,"a":6,"key":"28:6","ar":"وَنُمَكِّنَ لَهُمْ فِى ٱلْأَرْضِ وَنُرِىَ فِرْعَوْنَ وَهَـٰمَـٰنَ وَجُنُودَهُمَا مِنْهُم مَّا كَانُوا۟ يَحْذَرُونَ","en":"And establish them in the land and show Pharaoh and [his minister] Hāmān and their soldiers through them1 that which they had feared.","tr":"Wanumakkina lahum fee al-ardi wanuriyafirAAawna wahamana wajunoodahuma minhum makanoo yahtharoon","juz":20,"page":386},{"s":28,"a":7,"key":"28:7","ar":"وَأَوْحَيْنَآ إِلَىٰٓ أُمِّ مُوسَىٰٓ أَنْ أَرْضِعِيهِ ۖ فَإِذَا خِفْتِ عَلَيْهِ فَأَلْقِيهِ فِى ٱلْيَمِّ وَلَا تَخَافِى وَلَا تَحْزَنِىٓ ۖ إِنَّا رَآدُّوهُ إِلَيْكِ وَجَاعِلُوهُ مِنَ ٱلْمُرْسَلِينَ","en":"And We inspired to the mother of Moses, \"Suckle him; but when you fear for him, cast him into the river and do not fear and do not grieve. Indeed, We will return him to you and will make him [one] of the messengers.\"","tr":"Waawhayna ila ommi moosaan ardiAAeehi fa-itha khifti AAalayhi faalqeehi feealyammi wala takhafee wala tahzaneeinna raddoohu ilayki wajaAAiloohu minaalmursaleen","juz":20,"page":386},{"s":28,"a":8,"key":"28:8","ar":"فَٱلْتَقَطَهُۥٓ ءَالُ فِرْعَوْنَ لِيَكُونَ لَهُمْ عَدُوًّا وَحَزَنًا ۗ إِنَّ فِرْعَوْنَ وَهَـٰمَـٰنَ وَجُنُودَهُمَا كَانُوا۟ خَـٰطِـِٔينَ","en":"And the family of Pharaoh picked him up [out of the river] so that he would become to them an enemy and a [cause of] grief. Indeed, Pharaoh and Hāmān and their soldiers were deliberate sinners.","tr":"Faltaqatahu alufirAAawna liyakoona lahum AAaduwwan wahazanan innafirAAawna wahamana wajunoodahuma kanookhati-een","juz":20,"page":386},{"s":28,"a":9,"key":"28:9","ar":"وَقَالَتِ ٱمْرَأَتُ فِرْعَوْنَ قُرَّتُ عَيْنٍ لِّى وَلَكَ ۖ لَا تَقْتُلُوهُ عَسَىٰٓ أَن يَنفَعَنَآ أَوْ نَتَّخِذَهُۥ وَلَدًا وَهُمْ لَا يَشْعُرُونَ","en":"And the wife of Pharaoh said, \"[He will be] a comfort of the eye [i.e., pleasure] for me and for you. Do not kill him; perhaps he may benefit us, or we may adopt him as a son.\" And they perceived not.1","tr":"Waqalati imraatu firAAawna qurratuAAaynin lee walaka la taqtuloohu AAasa an yanfaAAanaaw nattakhithahu waladan wahum la yashAAuroon","juz":20,"page":386},{"s":28,"a":10,"key":"28:10","ar":"وَأَصْبَحَ فُؤَادُ أُمِّ مُوسَىٰ فَـٰرِغًا ۖ إِن كَادَتْ لَتُبْدِى بِهِۦ لَوْلَآ أَن رَّبَطْنَا عَلَىٰ قَلْبِهَا لِتَكُونَ مِنَ ٱلْمُؤْمِنِينَ","en":"And the heart of Moses' mother became empty [of all else]. She was about to disclose [the matter concerning] him had We not bound fast her heart that she would be of the believers.","tr":"Waasbaha fu-adu ommimoosa farighan in kadat latubdee bihi lawlaan rabatna AAala qalbiha litakoonamina almu/mineen","juz":20,"page":386},{"s":28,"a":11,"key":"28:11","ar":"وَقَالَتْ لِأُخْتِهِۦ قُصِّيهِ ۖ فَبَصُرَتْ بِهِۦ عَن جُنُبٍ وَهُمْ لَا يَشْعُرُونَ","en":"And she said to his sister, \"Follow him\"; so she watched him from a distance while they perceived not.","tr":"Waqalat li-okhtihi qusseehifabasurat bihi AAan junubin wahum la yashAAuroon","juz":20,"page":386},{"s":28,"a":12,"key":"28:12","ar":"۞ وَحَرَّمْنَا عَلَيْهِ ٱلْمَرَاضِعَ مِن قَبْلُ فَقَالَتْ هَلْ أَدُلُّكُمْ عَلَىٰٓ أَهْلِ بَيْتٍ يَكْفُلُونَهُۥ لَكُمْ وَهُمْ لَهُۥ نَـٰصِحُونَ","en":"And We had prevented from him [all] wet nurses before,1 so she said, \"Shall I direct you to a household that will be responsible for him for you while they are to him [for his upbringing] sincere?\"","tr":"Waharramna AAalayhi almaradiAAamin qablu faqalat hal adullukum AAala ahli baytinyakfuloonahu lakum wahum lahu nasihoon","juz":20,"page":386},{"s":28,"a":13,"key":"28:13","ar":"فَرَدَدْنَـٰهُ إِلَىٰٓ أُمِّهِۦ كَىْ تَقَرَّ عَيْنُهَا وَلَا تَحْزَنَ وَلِتَعْلَمَ أَنَّ وَعْدَ ٱللَّهِ حَقٌّ وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ","en":"So We restored him to his mother that she might be content and not grieve and that she would know that the promise of Allāh is true. But most of them [i.e., the people] do not know.","tr":"Faradadnahu ila ommihi kaytaqarra AAaynuha wala tahzana walitaAAlamaanna waAAda Allahi haqqun walakinnaaktharahum la yaAAlamoon","juz":20,"page":386},{"s":28,"a":14,"key":"28:14","ar":"وَلَمَّا بَلَغَ أَشُدَّهُۥ وَٱسْتَوَىٰٓ ءَاتَيْنَـٰهُ حُكْمًا وَعِلْمًا ۚ وَكَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ","en":"And when he attained his full strength and was [mentally] mature, We bestowed upon him judgement and knowledge. And thus do We reward the doers of good.","tr":"Walamma balagha ashuddahu wastawaataynahu hukman waAAilman wakathalikanajzee almuhsineen","juz":20,"page":387},{"s":28,"a":15,"key":"28:15","ar":"وَدَخَلَ ٱلْمَدِينَةَ عَلَىٰ حِينِ غَفْلَةٍ مِّنْ أَهْلِهَا فَوَجَدَ فِيهَا رَجُلَيْنِ يَقْتَتِلَانِ هَـٰذَا مِن شِيعَتِهِۦ وَهَـٰذَا مِنْ عَدُوِّهِۦ ۖ فَٱسْتَغَـٰثَهُ ٱلَّذِى مِن شِيعَتِهِۦ عَلَى ٱلَّذِى مِنْ عَدُوِّهِۦ فَوَكَزَهُۥ مُوسَىٰ فَقَضَىٰ عَلَيْهِ ۖ قَالَ هَـٰذَا مِنْ عَمَلِ ٱلشَّيْطَـٰنِ ۖ إِنَّهُۥ عَدُوٌّ مُّضِلٌّ مُّبِينٌ","en":"And he entered the city at a time of inattention by its people1 and found therein two men fighting: one from his faction and one from among his enemy. And the one from his faction called for help to him against the one from his enemy, so Moses struck him and [unintentionally] killed him. [Moses] said, \"This is from the work of Satan. Indeed, he is a manifest, misleading enemy.\"","tr":"Wadakhala almadeenata AAala heenighaflatin min ahliha fawajada feeha rajulayniyaqtatilani hatha min sheeAAatihi wahathamin AAaduwwihi fastaghathahu allathee minsheeAAatihi AAala allathee min AAaduwwihifawakazahu moosa faqada AAalayhi qala hathamin AAamali ashshaytani innahu AAaduwwun mudillunmubeen","juz":20,"page":387},{"s":28,"a":16,"key":"28:16","ar":"قَالَ رَبِّ إِنِّى ظَلَمْتُ نَفْسِى فَٱغْفِرْ لِى فَغَفَرَ لَهُۥٓ ۚ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ","en":"He said, \"My Lord, indeed I have wronged myself, so forgive me,\" and He forgave him. Indeed, He is the Forgiving, the Merciful.","tr":"Qala rabbi innee thalamtunafsee faghfir lee faghafara lahu innahu huwa alghafooruarraheem","juz":20,"page":387},{"s":28,"a":17,"key":"28:17","ar":"قَالَ رَبِّ بِمَآ أَنْعَمْتَ عَلَىَّ فَلَنْ أَكُونَ ظَهِيرًا لِّلْمُجْرِمِينَ","en":"He said, \"My Lord, for the favor You bestowed upon me, I will never be an assistant to the criminals.\"","tr":"Qala rabbi bima anAAamtaAAalayya falan akoona thaheeran lilmujrimeen","juz":20,"page":387},{"s":28,"a":18,"key":"28:18","ar":"فَأَصْبَحَ فِى ٱلْمَدِينَةِ خَآئِفًا يَتَرَقَّبُ فَإِذَا ٱلَّذِى ٱسْتَنصَرَهُۥ بِٱلْأَمْسِ يَسْتَصْرِخُهُۥ ۚ قَالَ لَهُۥ مُوسَىٰٓ إِنَّكَ لَغَوِىٌّ مُّبِينٌ","en":"And he became inside the city fearful and anticipating [exposure], when suddenly the one who sought his help the previous day cried out to him [once again]. Moses said to him, \"Indeed, you are an evident, [persistent] deviator.\"","tr":"Faasbaha fee almadeenati kha-ifanyataraqqabu fa-itha allathee istansarahu bil-amsiyastasrikhuhu qala lahu moosa innakalaghawiyyun mubeen","juz":20,"page":387},{"s":28,"a":19,"key":"28:19","ar":"فَلَمَّآ أَنْ أَرَادَ أَن يَبْطِشَ بِٱلَّذِى هُوَ عَدُوٌّ لَّهُمَا قَالَ يَـٰمُوسَىٰٓ أَتُرِيدُ أَن تَقْتُلَنِى كَمَا قَتَلْتَ نَفْسًۢا بِٱلْأَمْسِ ۖ إِن تُرِيدُ إِلَّآ أَن تَكُونَ جَبَّارًا فِى ٱلْأَرْضِ وَمَا تُرِيدُ أَن تَكُونَ مِنَ ٱلْمُصْلِحِينَ","en":"And when he wanted to strike the one who was an enemy to both of them, he1 said, \"O Moses, do you intend to kill me as you killed someone yesterday? You only want to be a tyrant in the land and do not want to be of the amenders.\"","tr":"Falamma an arada an yabtishabillathee huwa AAaduwwun lahuma qalaya moosa atureedu an taqtulanee kama qataltanafsan bil-amsi in tureedu illa an takoona jabbaranfee al-ardi wama tureedu an takoona mina almusliheen","juz":20,"page":387},{"s":28,"a":20,"key":"28:20","ar":"وَجَآءَ رَجُلٌ مِّنْ أَقْصَا ٱلْمَدِينَةِ يَسْعَىٰ قَالَ يَـٰمُوسَىٰٓ إِنَّ ٱلْمَلَأَ يَأْتَمِرُونَ بِكَ لِيَقْتُلُوكَ فَٱخْرُجْ إِنِّى لَكَ مِنَ ٱلنَّـٰصِحِينَ","en":"And a man came from the farthest end of the city, running. He said, \"O Moses, indeed the eminent ones are conferring over you [intending] to kill you, so leave [the city]; indeed, I am to you of the sincere advisors.\"","tr":"Wajaa rajulun min aqsaalmadeenati yasAAa qala ya moosa innaalmalaa ya/tamiroona bika liyaqtulooka fakhruj innee lakamina annasiheen","juz":20,"page":387},{"s":28,"a":21,"key":"28:21","ar":"فَخَرَجَ مِنْهَا خَآئِفًا يَتَرَقَّبُ ۖ قَالَ رَبِّ نَجِّنِى مِنَ ٱلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"So he left it, fearful and anticipating [apprehension]. He said, \"My Lord, save me from the wrongdoing people.\"","tr":"Fakharaja minha kha-ifanyataraqqabu qala rabbi najjinee mina alqawmi aththalimeen","juz":20,"page":387},{"s":28,"a":22,"key":"28:22","ar":"وَلَمَّا تَوَجَّهَ تِلْقَآءَ مَدْيَنَ قَالَ عَسَىٰ رَبِّىٓ أَن يَهْدِيَنِى سَوَآءَ ٱلسَّبِيلِ","en":"And when he directed himself toward Madyan, he said, \"Perhaps my Lord will guide me to the sound way.\"","tr":"Walamma tawajjaha tilqaamadyana qala AAasa rabbee an yahdiyanee sawaaassabeel","juz":20,"page":388},{"s":28,"a":23,"key":"28:23","ar":"وَلَمَّا وَرَدَ مَآءَ مَدْيَنَ وَجَدَ عَلَيْهِ أُمَّةً مِّنَ ٱلنَّاسِ يَسْقُونَ وَوَجَدَ مِن دُونِهِمُ ٱمْرَأَتَيْنِ تَذُودَانِ ۖ قَالَ مَا خَطْبُكُمَا ۖ قَالَتَا لَا نَسْقِى حَتَّىٰ يُصْدِرَ ٱلرِّعَآءُ ۖ وَأَبُونَا شَيْخٌ كَبِيرٌ","en":"And when he came to the water [i.e., well] of Madyan, he found there a crowd of people watering [their flocks], and he found aside from them two women holding back [their flocks]. He said, \"What is your circumstance?\" They said, \"We do not water until the shepherds dispatch [their flocks]; and our father is an old man.\"","tr":"Walamma warada maa madyanawajada AAalayhi ommatan mina annasi yasqoonawawajada min doonihimu imraatayni tathoodani qalama khatbukuma qalata lanasqee hatta yusdira arriAAaowaaboona shaykhun kabeer","juz":20,"page":388},{"s":28,"a":24,"key":"28:24","ar":"فَسَقَىٰ لَهُمَا ثُمَّ تَوَلَّىٰٓ إِلَى ٱلظِّلِّ فَقَالَ رَبِّ إِنِّى لِمَآ أَنزَلْتَ إِلَىَّ مِنْ خَيْرٍ فَقِيرٌ","en":"So he watered [their flocks] for them; then he went back to the shade and said, \"My Lord, indeed I am, for whatever good You would send down to me, in need.\"","tr":"Fasaqa lahuma thumma tawallaila aththilli faqala rabbiinnee lima anzalta ilayya min khayrin faqeer","juz":20,"page":388},{"s":28,"a":25,"key":"28:25","ar":"فَجَآءَتْهُ إِحْدَىٰهُمَا تَمْشِى عَلَى ٱسْتِحْيَآءٍ قَالَتْ إِنَّ أَبِى يَدْعُوكَ لِيَجْزِيَكَ أَجْرَ مَا سَقَيْتَ لَنَا ۚ فَلَمَّا جَآءَهُۥ وَقَصَّ عَلَيْهِ ٱلْقَصَصَ قَالَ لَا تَخَفْ ۖ نَجَوْتَ مِنَ ٱلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"Then one of the two women came to him walking with shyness. She said, \"Indeed, my father invites you that he may reward you for having watered for us.\" So when he came to him1 and related to him the story, he said, \"Fear not. You have escaped from the wrongdoing people.\"","tr":"Fajaat-hu ihdahumatamshee AAala istihya-in qalat innaabee yadAAooka liyajziyaka ajra ma saqayta lanafalamma jaahu waqassa AAalayhi alqasasaqala la takhaf najawta mina alqawmi aththalimeen","juz":20,"page":388},{"s":28,"a":26,"key":"28:26","ar":"قَالَتْ إِحْدَىٰهُمَا يَـٰٓأَبَتِ ٱسْتَـْٔجِرْهُ ۖ إِنَّ خَيْرَ مَنِ ٱسْتَـْٔجَرْتَ ٱلْقَوِىُّ ٱلْأَمِينُ","en":"One of the women said, \"O my father, hire him. Indeed, the best one you can hire is the strong and the trustworthy.\"","tr":"Qalat ihdahuma yaabati ista/jirhu inna khayra mani ista/jarta alqawiyyu al-ameen","juz":20,"page":388},{"s":28,"a":27,"key":"28:27","ar":"قَالَ إِنِّىٓ أُرِيدُ أَنْ أُنكِحَكَ إِحْدَى ٱبْنَتَىَّ هَـٰتَيْنِ عَلَىٰٓ أَن تَأْجُرَنِى ثَمَـٰنِىَ حِجَجٍ ۖ فَإِنْ أَتْمَمْتَ عَشْرًا فَمِنْ عِندِكَ ۖ وَمَآ أُرِيدُ أَنْ أَشُقَّ عَلَيْكَ ۚ سَتَجِدُنِىٓ إِن شَآءَ ٱللَّهُ مِنَ ٱلصَّـٰلِحِينَ","en":"He said, \"Indeed, I wish to wed you one of these, my two daughters, on [the condition] that you serve me for eight years; but if you complete ten, it will be [as a favor] from you. And I do not wish to put you in difficulty. You will find me, if Allāh wills, from among the righteous.\"","tr":"Qala innee oreedu an onkihakaihda ibnatayya hatayni AAala anta/juranee thamaniya hijajin fa-in atmamta AAashranfamin AAindika wama oreedu an ashuqqa AAalayka satajiduneein shaa Allahu mina assaliheen","juz":20,"page":388},{"s":28,"a":28,"key":"28:28","ar":"قَالَ ذَٰلِكَ بَيْنِى وَبَيْنَكَ ۖ أَيَّمَا ٱلْأَجَلَيْنِ قَضَيْتُ فَلَا عُدْوَٰنَ عَلَىَّ ۖ وَٱللَّهُ عَلَىٰ مَا نَقُولُ وَكِيلٌ","en":"[Moses] said, \"That is [established] between me and you. Whichever of the two terms I complete - there is no injustice to me, and Allāh, over what we say, is Witness.\"","tr":"Qala thalika baynee wabaynakaayyama al-ajalayni qadaytu fala AAudwanaAAalayya wallahu AAala ma naqooluwakeel","juz":20,"page":388},{"s":28,"a":29,"key":"28:29","ar":"۞ فَلَمَّا قَضَىٰ مُوسَى ٱلْأَجَلَ وَسَارَ بِأَهْلِهِۦٓ ءَانَسَ مِن جَانِبِ ٱلطُّورِ نَارًا قَالَ لِأَهْلِهِ ٱمْكُثُوٓا۟ إِنِّىٓ ءَانَسْتُ نَارًا لَّعَلِّىٓ ءَاتِيكُم مِّنْهَا بِخَبَرٍ أَوْ جَذْوَةٍ مِّنَ ٱلنَّارِ لَعَلَّكُمْ تَصْطَلُونَ","en":"And when Moses had completed the term and was traveling with his family, he perceived from the direction of the mount a fire. He said to his family, \"Stay here; indeed, I have perceived a fire. Perhaps I will bring you from there [some] information or burning wood from the fire that you may warm yourselves.\"","tr":"Falamma qada moosaal-ajala wasara bi-ahlihi anasa min janibi attoorinaran qala li-ahlihi omkuthoo innee anastu naranlaAAallee ateekum minha bikhabarin aw jathwatinmina annari laAAallakum tastaloon","juz":20,"page":389},{"s":28,"a":30,"key":"28:30","ar":"فَلَمَّآ أَتَىٰهَا نُودِىَ مِن شَـٰطِئِ ٱلْوَادِ ٱلْأَيْمَنِ فِى ٱلْبُقْعَةِ ٱلْمُبَـٰرَكَةِ مِنَ ٱلشَّجَرَةِ أَن يَـٰمُوسَىٰٓ إِنِّىٓ أَنَا ٱللَّهُ رَبُّ ٱلْعَـٰلَمِينَ","en":"But when he came to it, he was called from the right side of the valley in a blessed spot - from the tree,1 \"O Moses, indeed I am Allāh, Lord of the worlds.\"","tr":"Falamma ataha noodiyamin shati-i alwadi al-aymani fee albuqAAati almubarakatimina ashshajarati an ya moosa innee anaAllahu rabbu alAAalameen","juz":20,"page":389},{"s":28,"a":31,"key":"28:31","ar":"وَأَنْ أَلْقِ عَصَاكَ ۖ فَلَمَّا رَءَاهَا تَهْتَزُّ كَأَنَّهَا جَآنٌّ وَلَّىٰ مُدْبِرًا وَلَمْ يُعَقِّبْ ۚ يَـٰمُوسَىٰٓ أَقْبِلْ وَلَا تَخَفْ ۖ إِنَّكَ مِنَ ٱلْـَٔامِنِينَ","en":"And [he was told], \"Throw down your staff.\" But when he saw it writhing as if it was a snake, he turned in flight and did not return.1 [Allāh said], \"O Moses, approach and fear not. Indeed, you are of the secure.","tr":"Waan alqi AAasaka falamma raahatahtazzu kaannaha jannun walla mudbiranwalam yuAAaqqib ya moosa aqbil wala takhafinnaka mina al-amineen","juz":20,"page":389},{"s":28,"a":32,"key":"28:32","ar":"ٱسْلُكْ يَدَكَ فِى جَيْبِكَ تَخْرُجْ بَيْضَآءَ مِنْ غَيْرِ سُوٓءٍ وَٱضْمُمْ إِلَيْكَ جَنَاحَكَ مِنَ ٱلرَّهْبِ ۖ فَذَٰنِكَ بُرْهَـٰنَانِ مِن رَّبِّكَ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦٓ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًا فَـٰسِقِينَ","en":"Insert your hand into the opening of your garment; it will come out white, without disease. And draw in your arm close to you [as prevention] from fear, for those are two proofs from your Lord to Pharaoh and his establishment. Indeed, they have been a people defiantly disobedient.\"","tr":"Osluk yadaka fee jaybika takhruj baydaamin ghayri soo-in wadmum ilayka janahakamina arrahbi fathanika burhanani minrabbika ila firAAawna wamala-ihi innahum kanooqawman fasiqeen","juz":20,"page":389},{"s":28,"a":33,"key":"28:33","ar":"قَالَ رَبِّ إِنِّى قَتَلْتُ مِنْهُمْ نَفْسًا فَأَخَافُ أَن يَقْتُلُونِ","en":"He said, \"My Lord, indeed I killed from among them someone, and I fear they will kill me.","tr":"Qala rabbi innee qataltu minhumnafsan faakhafu an yaqtuloon","juz":20,"page":389},{"s":28,"a":34,"key":"28:34","ar":"وَأَخِى هَـٰرُونُ هُوَ أَفْصَحُ مِنِّى لِسَانًا فَأَرْسِلْهُ مَعِىَ رِدْءًا يُصَدِّقُنِىٓ ۖ إِنِّىٓ أَخَافُ أَن يُكَذِّبُونِ","en":"And my brother Aaron is more fluent than me in tongue, so send him with me as support, verifying me. Indeed, I fear that they will deny me.\"","tr":"Waakhee haroonu huwa afsahuminnee lisanan faarsilhu maAAiya rid-an yusaddiquneeinnee akhafu an yukaththiboon","juz":20,"page":389},{"s":28,"a":35,"key":"28:35","ar":"قَالَ سَنَشُدُّ عَضُدَكَ بِأَخِيكَ وَنَجْعَلُ لَكُمَا سُلْطَـٰنًا فَلَا يَصِلُونَ إِلَيْكُمَا ۚ بِـَٔايَـٰتِنَآ أَنتُمَا وَمَنِ ٱتَّبَعَكُمَا ٱلْغَـٰلِبُونَ","en":"[Allāh] said, \"We will strengthen your arm through your brother and grant you both supremacy so they will not reach you. [It will be] through Our signs; you and those who follow you will be the predominant.\"","tr":"Qala sanashuddu AAadudakabi-akheeka wanajAAalu lakuma sultanan falayasiloona ilaykuma bi-ayatinaantuma wamani ittabaAAakuma alghaliboon","juz":20,"page":389},{"s":28,"a":36,"key":"28:36","ar":"فَلَمَّا جَآءَهُم مُّوسَىٰ بِـَٔايَـٰتِنَا بَيِّنَـٰتٍ قَالُوا۟ مَا هَـٰذَآ إِلَّا سِحْرٌ مُّفْتَرًى وَمَا سَمِعْنَا بِهَـٰذَا فِىٓ ءَابَآئِنَا ٱلْأَوَّلِينَ","en":"But when Moses came to them with Our signs as clear evidences, they said, \"This is not except invented magic, and we have not heard of this [religion] among our forefathers.\"","tr":"Falamma jaahum moosabi-ayatina bayyinatin qaloo mahatha illa sihrun muftaran wamasamiAAna bihatha fee aba-inaal-awwaleen","juz":20,"page":390},{"s":28,"a":37,"key":"28:37","ar":"وَقَالَ مُوسَىٰ رَبِّىٓ أَعْلَمُ بِمَن جَآءَ بِٱلْهُدَىٰ مِنْ عِندِهِۦ وَمَن تَكُونُ لَهُۥ عَـٰقِبَةُ ٱلدَّارِ ۖ إِنَّهُۥ لَا يُفْلِحُ ٱلظَّـٰلِمُونَ","en":"And Moses said, \"My Lord is more knowing [than we or you] of who has come with guidance from Him and to whom will be succession in the home.1 Indeed, wrongdoers do not succeed.\"","tr":"Waqala moosa rabbee aAAlamubiman jaa bilhuda min AAindihi wamantakoonu lahu AAaqibatu addari innahu layuflihu aththalimoon","juz":20,"page":390},{"s":28,"a":38,"key":"28:38","ar":"وَقَالَ فِرْعَوْنُ يَـٰٓأَيُّهَا ٱلْمَلَأُ مَا عَلِمْتُ لَكُم مِّنْ إِلَـٰهٍ غَيْرِى فَأَوْقِدْ لِى يَـٰهَـٰمَـٰنُ عَلَى ٱلطِّينِ فَٱجْعَل لِّى صَرْحًا لَّعَلِّىٓ أَطَّلِعُ إِلَىٰٓ إِلَـٰهِ مُوسَىٰ وَإِنِّى لَأَظُنُّهُۥ مِنَ ٱلْكَـٰذِبِينَ","en":"And Pharaoh said, \"O eminent ones, I have not known you to have a god other than me. Then ignite for me, O Hāmān, [a fire] upon the clay1 and make for me a tower that I may look at the God of Moses. And indeed, I do think he is among the liars.\"","tr":"Waqala firAAawnu ya ayyuhaalmalao ma AAalimtu lakum min ilahin ghayreefaawqid lee ya hamanu AAala atteenifajAAal lee sarhan laAAallee attaliAAuila ilahi moosa wa-innee laathunnuhumina alkathibeen","juz":20,"page":390},{"s":28,"a":39,"key":"28:39","ar":"وَٱسْتَكْبَرَ هُوَ وَجُنُودُهُۥ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَظَنُّوٓا۟ أَنَّهُمْ إِلَيْنَا لَا يُرْجَعُونَ","en":"And he was arrogant, he and his soldiers, in the land, without right, and they thought that they would not be returned to Us.","tr":"Wastakbara huwa wajunooduhu feeal-ardi bighayri alhaqqi wathannooannahum ilayna la yurjaAAoon","juz":20,"page":390},{"s":28,"a":40,"key":"28:40","ar":"فَأَخَذْنَـٰهُ وَجُنُودَهُۥ فَنَبَذْنَـٰهُمْ فِى ٱلْيَمِّ ۖ فَٱنظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ٱلظَّـٰلِمِينَ","en":"So We took him and his soldiers and threw them into the sea.1 So see how was the end of the wrongdoers.","tr":"Faakhathnahu wajunoodahufanabathnahum fee alyammi fanthurkayfa kana AAaqibatu aththalimeen","juz":20,"page":390},{"s":28,"a":41,"key":"28:41","ar":"وَجَعَلْنَـٰهُمْ أَئِمَّةً يَدْعُونَ إِلَى ٱلنَّارِ ۖ وَيَوْمَ ٱلْقِيَـٰمَةِ لَا يُنصَرُونَ","en":"And We made them leaders1 inviting to the Fire, and on the Day of Resurrection they will not be helped.","tr":"WajaAAalnahum a-immatan yadAAoona ilaannari wayawma alqiyamati la yunsaroon","juz":20,"page":390},{"s":28,"a":42,"key":"28:42","ar":"وَأَتْبَعْنَـٰهُمْ فِى هَـٰذِهِ ٱلدُّنْيَا لَعْنَةً ۖ وَيَوْمَ ٱلْقِيَـٰمَةِ هُم مِّنَ ٱلْمَقْبُوحِينَ","en":"And We caused to overtake them in this world a curse, and on the Day of Resurrection they will be of the despised.1","tr":"WaatbaAAnahum fee hathihi addunyalaAAnatan wayawma alqiyamati hum mina almaqbooheen","juz":20,"page":390},{"s":28,"a":43,"key":"28:43","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ مِنۢ بَعْدِ مَآ أَهْلَكْنَا ٱلْقُرُونَ ٱلْأُولَىٰ بَصَآئِرَ لِلنَّاسِ وَهُدًى وَرَحْمَةً لَّعَلَّهُمْ يَتَذَكَّرُونَ","en":"And We gave Moses the Scripture, after We had destroyed the former generations, as enlightenment for the people and guidance and mercy that they might be reminded.","tr":"Walaqad atayna moosaalkitaba min baAAdi ma ahlakna alquroonaal-oola basa-ira linnasi wahudanwarahmatan laAAallahum yatathakkaroon","juz":20,"page":390},{"s":28,"a":44,"key":"28:44","ar":"وَمَا كُنتَ بِجَانِبِ ٱلْغَرْبِىِّ إِذْ قَضَيْنَآ إِلَىٰ مُوسَى ٱلْأَمْرَ وَمَا كُنتَ مِنَ ٱلشَّـٰهِدِينَ","en":"And you, [O Muḥammad], were not on the western side [of the mount] when We revealed to Moses the command, and you were not among the witnesses [to that].","tr":"Wama kunta bijanibialgharbiyyi ith qadayna ila moosaal-amra wama kunta mina ashshahideen","juz":20,"page":391},{"s":28,"a":45,"key":"28:45","ar":"وَلَـٰكِنَّآ أَنشَأْنَا قُرُونًا فَتَطَاوَلَ عَلَيْهِمُ ٱلْعُمُرُ ۚ وَمَا كُنتَ ثَاوِيًا فِىٓ أَهْلِ مَدْيَنَ تَتْلُوا۟ عَلَيْهِمْ ءَايَـٰتِنَا وَلَـٰكِنَّا كُنَّا مُرْسِلِينَ","en":"But We produced [many] generations [after Moses], and prolonged was their duration.1 And you were not a resident among the people of Madyan, reciting to them Our verses, but We were senders [of this message].2","tr":"Walakinna ansha-naquroonan fatatawala AAalayhimu alAAumuru wama kuntathawiyan fee ahli madyana tatloo AAalayhim ayatinawalakinna kunna mursileen","juz":20,"page":391},{"s":28,"a":46,"key":"28:46","ar":"وَمَا كُنتَ بِجَانِبِ ٱلطُّورِ إِذْ نَادَيْنَا وَلَـٰكِن رَّحْمَةً مِّن رَّبِّكَ لِتُنذِرَ قَوْمًا مَّآ أَتَىٰهُم مِّن نَّذِيرٍ مِّن قَبْلِكَ لَعَلَّهُمْ يَتَذَكَّرُونَ","en":"And you were not at the side of the mount when We called [Moses] but [were sent] as a mercy from your Lord to warn a people to whom no warner had come before you that they might be reminded.","tr":"Wama kunta bijanibi attooriith nadayna walakin rahmatanmin rabbika litunthira qawman ma atahum minnatheerin min qablika laAAallahum yatathakkaroon","juz":20,"page":391},{"s":28,"a":47,"key":"28:47","ar":"وَلَوْلَآ أَن تُصِيبَهُم مُّصِيبَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ فَيَقُولُوا۟ رَبَّنَا لَوْلَآ أَرْسَلْتَ إِلَيْنَا رَسُولًا فَنَتَّبِعَ ءَايَـٰتِكَ وَنَكُونَ مِنَ ٱلْمُؤْمِنِينَ","en":"And if not that a disaster should strike them for what their hands put forth [of sins] and they would say, \"Our Lord, why did You not send us a messenger so we could have followed Your verses and been among the believers?\"...1","tr":"Walawla an tuseebahum museebatunbima qaddamat aydeehim fayaqooloo rabbana lawlaarsalta ilayna rasoolan fanattabiAAa ayatikawanakoona mina almu/mineen","juz":20,"page":391},{"s":28,"a":48,"key":"28:48","ar":"فَلَمَّا جَآءَهُمُ ٱلْحَقُّ مِنْ عِندِنَا قَالُوا۟ لَوْلَآ أُوتِىَ مِثْلَ مَآ أُوتِىَ مُوسَىٰٓ ۚ أَوَلَمْ يَكْفُرُوا۟ بِمَآ أُوتِىَ مُوسَىٰ مِن قَبْلُ ۖ قَالُوا۟ سِحْرَانِ تَظَـٰهَرَا وَقَالُوٓا۟ إِنَّا بِكُلٍّ كَـٰفِرُونَ","en":"But when the truth came to them from Us, they said, \"Why was he not given like that which was given to Moses?\" Did they not disbelieve in that which was given to Moses before? They said, \"[They are but] two works of magic supporting each other,1 and indeed we are, in both, disbelievers.\"","tr":"Falamma jaahumu alhaqqumin AAindina qaloo lawla ootiya mithla maootiya moosa awa lam yakfuroo bima ootiya moosamin qablu qaloo sihrani tathaharawaqaloo inna bikullin kafiroon","juz":20,"page":391},{"s":28,"a":49,"key":"28:49","ar":"قُلْ فَأْتُوا۟ بِكِتَـٰبٍ مِّنْ عِندِ ٱللَّهِ هُوَ أَهْدَىٰ مِنْهُمَآ أَتَّبِعْهُ إِن كُنتُمْ صَـٰدِقِينَ","en":"Say, \"Then bring a scripture from Allāh which is more guiding than either of them that I may follow it, if you should be truthful.\"","tr":"Qul fa/too bikitabin min AAindi Allahihuwa ahda minhuma attabiAAhu in kuntum sadiqeen","juz":20,"page":391},{"s":28,"a":50,"key":"28:50","ar":"فَإِن لَّمْ يَسْتَجِيبُوا۟ لَكَ فَٱعْلَمْ أَنَّمَا يَتَّبِعُونَ أَهْوَآءَهُمْ ۚ وَمَنْ أَضَلُّ مِمَّنِ ٱتَّبَعَ هَوَىٰهُ بِغَيْرِ هُدًى مِّنَ ٱللَّهِ ۚ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"But if they do not respond to you - then know that they only follow their [own] desires. And who is more astray than one who follows his desire without guidance from Allāh? Indeed, Allāh does not guide the wrongdoing people.","tr":"Fa-in lam yastajeeboo laka faAAlamannama yattabiAAoona ahwaahum waman adallumimmani ittabaAAa hawahu bighayri hudan mina Allahiinna Allaha la yahdee alqawma aththalimeen","juz":20,"page":391},{"s":28,"a":51,"key":"28:51","ar":"۞ وَلَقَدْ وَصَّلْنَا لَهُمُ ٱلْقَوْلَ لَعَلَّهُمْ يَتَذَكَّرُونَ","en":"And We have [repeatedly] conveyed to them the word [i.e., the Qur’ān] that they might be reminded.","tr":"Walaqad wassalna lahumualqawla laAAallahum yatathakkaroon","juz":20,"page":392},{"s":28,"a":52,"key":"28:52","ar":"ٱلَّذِينَ ءَاتَيْنَـٰهُمُ ٱلْكِتَـٰبَ مِن قَبْلِهِۦ هُم بِهِۦ يُؤْمِنُونَ","en":"Those to whom We gave the Scripture before it - they1 are believers in it.","tr":"Allatheena ataynahumualkitaba min qablihi hum bihi yu/minoon","juz":20,"page":392},{"s":28,"a":53,"key":"28:53","ar":"وَإِذَا يُتْلَىٰ عَلَيْهِمْ قَالُوٓا۟ ءَامَنَّا بِهِۦٓ إِنَّهُ ٱلْحَقُّ مِن رَّبِّنَآ إِنَّا كُنَّا مِن قَبْلِهِۦ مُسْلِمِينَ","en":"And when it is recited to them, they say, \"We have believed in it; indeed, it is the truth from our Lord. Indeed we were, [even] before it, Muslims [i.e., submitting to Allāh].\"","tr":"Wa-itha yutla AAalayhim qalooamanna bihi innahu alhaqqu min rabbinainna kunna min qablihi muslimeen","juz":20,"page":392},{"s":28,"a":54,"key":"28:54","ar":"أُو۟لَـٰٓئِكَ يُؤْتَوْنَ أَجْرَهُم مَّرَّتَيْنِ بِمَا صَبَرُوا۟ وَيَدْرَءُونَ بِٱلْحَسَنَةِ ٱلسَّيِّئَةَ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَ","en":"Those will be given their reward twice for what they patiently endured and [because] they avert evil through good, and from what We have provided them they spend.","tr":"Ola-ika yu/tawna ajrahum marrataynibima sabaroo wayadraoona bilhasanatiassayyi-ata wamimma razaqnahum yunfiqoon","juz":20,"page":392},{"s":28,"a":55,"key":"28:55","ar":"وَإِذَا سَمِعُوا۟ ٱللَّغْوَ أَعْرَضُوا۟ عَنْهُ وَقَالُوا۟ لَنَآ أَعْمَـٰلُنَا وَلَكُمْ أَعْمَـٰلُكُمْ سَلَـٰمٌ عَلَيْكُمْ لَا نَبْتَغِى ٱلْجَـٰهِلِينَ","en":"And when they hear ill speech, they turn away from it and say, \"For us are our deeds, and for you are your deeds. Peace will be upon you;1 we seek not the ignorant.\"","tr":"Wa-itha samiAAoo allaghwa aAAradooAAanhu waqaloo lana aAAmaluna walakumaAAmalukum salamun AAalaykum la nabtagheealjahileen","juz":20,"page":392},{"s":28,"a":56,"key":"28:56","ar":"إِنَّكَ لَا تَهْدِى مَنْ أَحْبَبْتَ وَلَـٰكِنَّ ٱللَّهَ يَهْدِى مَن يَشَآءُ ۚ وَهُوَ أَعْلَمُ بِٱلْمُهْتَدِينَ","en":"Indeed, [O Muḥammad], you do not guide whom you like, but Allāh guides whom He wills. And He is most knowing of the [rightly] guided.","tr":"Innaka la tahdee man ahbabtawalakinna Allaha yahdee man yashao wahuwaaAAlamu bilmuhtadeen","juz":20,"page":392},{"s":28,"a":57,"key":"28:57","ar":"وَقَالُوٓا۟ إِن نَّتَّبِعِ ٱلْهُدَىٰ مَعَكَ نُتَخَطَّفْ مِنْ أَرْضِنَآ ۚ أَوَلَمْ نُمَكِّن لَّهُمْ حَرَمًا ءَامِنًا يُجْبَىٰٓ إِلَيْهِ ثَمَرَٰتُ كُلِّ شَىْءٍ رِّزْقًا مِّن لَّدُنَّا وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ","en":"And they [i.e., the Quraysh] say, \"If we were to follow the guidance with you, we would be swept1 from our land.\" Have We not established for them a safe sanctuary to which are brought the fruits of all things as provision from Us? But most of them do not know.","tr":"Waqaloo in nattabiAAi alhudamaAAaka nutakhattaf min ardina awa lamnumakkin lahum haraman aminan yujba ilayhithamaratu kulli shay-in rizqan min ladunna walakinnaaktharahum la yaAAlamoon","juz":20,"page":392},{"s":28,"a":58,"key":"28:58","ar":"وَكَمْ أَهْلَكْنَا مِن قَرْيَةٍۭ بَطِرَتْ مَعِيشَتَهَا ۖ فَتِلْكَ مَسَـٰكِنُهُمْ لَمْ تُسْكَن مِّنۢ بَعْدِهِمْ إِلَّا قَلِيلًا ۖ وَكُنَّا نَحْنُ ٱلْوَٰرِثِينَ","en":"And how many a city have We destroyed that was insolent in its [way of] living, and those are their dwellings which have not been inhabited after them except briefly.1 And it is We who were the inheritors.","tr":"Wakam ahlakna min qaryatin batiratmaAAeeshataha fatilka masakinuhum lam tuskan minbaAAdihim illa qaleelan wakunna nahnu alwaritheen","juz":20,"page":392},{"s":28,"a":59,"key":"28:59","ar":"وَمَا كَانَ رَبُّكَ مُهْلِكَ ٱلْقُرَىٰ حَتَّىٰ يَبْعَثَ فِىٓ أُمِّهَا رَسُولًا يَتْلُوا۟ عَلَيْهِمْ ءَايَـٰتِنَا ۚ وَمَا كُنَّا مُهْلِكِى ٱلْقُرَىٰٓ إِلَّا وَأَهْلُهَا ظَـٰلِمُونَ","en":"And never would your Lord have destroyed the cities until He had sent to their mother [i.e., principal city] a messenger reciting to them Our verses. And We would not destroy the cities except while their people were wrongdoers.","tr":"Wama kana rabbuka muhlikaalqura hatta yabAAatha fee ommiharasoolan yatloo AAalayhim ayatina wamakunna muhlikee alqura illa waahluha thalimoon","juz":20,"page":392},{"s":28,"a":60,"key":"28:60","ar":"وَمَآ أُوتِيتُم مِّن شَىْءٍ فَمَتَـٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا وَزِينَتُهَا ۚ وَمَا عِندَ ٱللَّهِ خَيْرٌ وَأَبْقَىٰٓ ۚ أَفَلَا تَعْقِلُونَ","en":"And whatever thing you [people] have been given - it is [only for] the enjoyment of worldly life and its adornment. And what is with Allāh is better and more lasting; so will you not use reason?","tr":"Wama ooteetum min shay-in famataAAualhayati addunya wazeenatuhawama AAinda Allahi khayrun waabqa afalataAAqiloon","juz":20,"page":393},{"s":28,"a":61,"key":"28:61","ar":"أَفَمَن وَعَدْنَـٰهُ وَعْدًا حَسَنًا فَهُوَ لَـٰقِيهِ كَمَن مَّتَّعْنَـٰهُ مَتَـٰعَ ٱلْحَيَوٰةِ ٱلدُّنْيَا ثُمَّ هُوَ يَوْمَ ٱلْقِيَـٰمَةِ مِنَ ٱلْمُحْضَرِينَ","en":"Then is he whom We have promised a good promise which he will meet [i.e., obtain] like he for whom We provided enjoyment of worldly life [but] then he is, on the Day of Resurrection, among those presented [for punishment in Hell]?","tr":"Afaman waAAadnahu waAAdan hasananfahuwa laqeehi kaman mattaAAnahu mataAAa alhayatiaddunya thumma huwa yawma alqiyamati minaalmuhdareen","juz":20,"page":393},{"s":28,"a":62,"key":"28:62","ar":"وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ أَيْنَ شُرَكَآءِىَ ٱلَّذِينَ كُنتُمْ تَزْعُمُونَ","en":"And [warn of] the Day He will call them and say, \"Where are My 'partners' which you used to claim?\"","tr":"Wayawma yunadeehim fayaqoolu aynashuraka-iya allatheena kuntum tazAAumoon","juz":20,"page":393},{"s":28,"a":63,"key":"28:63","ar":"قَالَ ٱلَّذِينَ حَقَّ عَلَيْهِمُ ٱلْقَوْلُ رَبَّنَا هَـٰٓؤُلَآءِ ٱلَّذِينَ أَغْوَيْنَآ أَغْوَيْنَـٰهُمْ كَمَا غَوَيْنَا ۖ تَبَرَّأْنَآ إِلَيْكَ ۖ مَا كَانُوٓا۟ إِيَّانَا يَعْبُدُونَ","en":"Those upon whom the word1 will have come into effect will say, \"Our Lord, these are the ones we led to error. We led them to error just as we were in error. We declare our disassociation [from them] to You. They did not used to worship [i.e., obey] us.\"2","tr":"Qala allatheena haqqaAAalayhimu alqawlu rabbana haola-i allatheenaaghwayna aghwaynahum kama ghawaynatabarra/na ilayka ma kanoo iyyanayaAAbudoon","juz":20,"page":393},{"s":28,"a":64,"key":"28:64","ar":"وَقِيلَ ٱدْعُوا۟ شُرَكَآءَكُمْ فَدَعَوْهُمْ فَلَمْ يَسْتَجِيبُوا۟ لَهُمْ وَرَأَوُا۟ ٱلْعَذَابَ ۚ لَوْ أَنَّهُمْ كَانُوا۟ يَهْتَدُونَ","en":"And it will be said, \"Invoke your 'partners,'\" and they will invoke them; but they will not respond to them, and they will see the punishment. If only they had followed guidance!","tr":"Waqeela odAAoo shurakaakumfadaAAawhum falam yastajeeboo lahum waraawoo alAAathabalaw annahum kanoo yahtadoon","juz":20,"page":393},{"s":28,"a":65,"key":"28:65","ar":"وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ مَاذَآ أَجَبْتُمُ ٱلْمُرْسَلِينَ","en":"And [mention] the Day He will call them and say, \"What did you answer the messengers?\"","tr":"Wayawma yunadeehim fayaqoolu mathaajabtumu almursaleen","juz":20,"page":393},{"s":28,"a":66,"key":"28:66","ar":"فَعَمِيَتْ عَلَيْهِمُ ٱلْأَنۢبَآءُ يَوْمَئِذٍ فَهُمْ لَا يَتَسَآءَلُونَ","en":"But the information1 will be unapparent to them that Day, so they will not [be able to] ask one another.","tr":"FaAAamiyat AAalayhimu al-anbaoyawma-ithin fahum la yatasaaloon","juz":20,"page":393},{"s":28,"a":67,"key":"28:67","ar":"فَأَمَّا مَن تَابَ وَءَامَنَ وَعَمِلَ صَـٰلِحًا فَعَسَىٰٓ أَن يَكُونَ مِنَ ٱلْمُفْلِحِينَ","en":"But as for one who had repented, believed, and done righteousness, it is expected [i.e., promised by Allāh] that he will be among the successful.","tr":"Faamma man taba waamanawaAAamila salihan faAAasa an yakoona minaalmufliheen","juz":20,"page":393},{"s":28,"a":68,"key":"28:68","ar":"وَرَبُّكَ يَخْلُقُ مَا يَشَآءُ وَيَخْتَارُ ۗ مَا كَانَ لَهُمُ ٱلْخِيَرَةُ ۚ سُبْحَـٰنَ ٱللَّهِ وَتَعَـٰلَىٰ عَمَّا يُشْرِكُونَ","en":"And your Lord creates what He wills and chooses; not for them was the choice. Exalted is Allāh and high above what they associate with Him.","tr":"Warabbuka yakhluqu ma yashaowayakhtaru ma kana lahumu alkhiyaratu subhanaAllahi wataAAala AAamma yushrikoon","juz":20,"page":393},{"s":28,"a":69,"key":"28:69","ar":"وَرَبُّكَ يَعْلَمُ مَا تُكِنُّ صُدُورُهُمْ وَمَا يُعْلِنُونَ","en":"And your Lord knows what their breasts conceal and what they declare.","tr":"Warabbuka yaAAlamu ma tukinnu sudooruhumwama yuAAlinoon","juz":20,"page":393},{"s":28,"a":70,"key":"28:70","ar":"وَهُوَ ٱللَّهُ لَآ إِلَـٰهَ إِلَّا هُوَ ۖ لَهُ ٱلْحَمْدُ فِى ٱلْأُولَىٰ وَٱلْـَٔاخِرَةِ ۖ وَلَهُ ٱلْحُكْمُ وَإِلَيْهِ تُرْجَعُونَ","en":"And He is Allāh; there is no deity except Him. To Him is [due all] praise in the first [life] and the Hereafter. And His is the [final] decision, and to Him you will be returned.","tr":"Wahuwa Allahu la ilahailla huwa lahu alhamdu fee al-oola wal-akhiratiwalahu alhukmu wa-ilayhi turjaAAoon","juz":20,"page":393},{"s":28,"a":71,"key":"28:71","ar":"قُلْ أَرَءَيْتُمْ إِن جَعَلَ ٱللَّهُ عَلَيْكُمُ ٱلَّيْلَ سَرْمَدًا إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ مَنْ إِلَـٰهٌ غَيْرُ ٱللَّهِ يَأْتِيكُم بِضِيَآءٍ ۖ أَفَلَا تَسْمَعُونَ","en":"Say, \"Have you considered:1 if Allāh should make for you the night continuous until the Day of Resurrection, what deity other than Allāh could bring you light? Then will you not hear?\"","tr":"Qul araaytum in jaAAala AllahuAAalaykumu allayla sarmadan ila yawmi alqiyamatiman ilahun ghayru Allahi ya/teekum bidiya-inafala tasmaAAoon","juz":20,"page":394},{"s":28,"a":72,"key":"28:72","ar":"قُلْ أَرَءَيْتُمْ إِن جَعَلَ ٱللَّهُ عَلَيْكُمُ ٱلنَّهَارَ سَرْمَدًا إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ مَنْ إِلَـٰهٌ غَيْرُ ٱللَّهِ يَأْتِيكُم بِلَيْلٍ تَسْكُنُونَ فِيهِ ۖ أَفَلَا تُبْصِرُونَ","en":"Say, \"Have you considered: if Allāh should make for you the day continuous until the Day of Resurrection, what deity other than Allāh could bring you a night in which you may rest? Then will you not see?\"","tr":"Qul araaytum in jaAAala AllahuAAalaykumu annahara sarmadan ila yawmialqiyamati man ilahun ghayru Allahiya/teekum bilaylin taskunoona feehi afala tubsiroon","juz":20,"page":394},{"s":28,"a":73,"key":"28:73","ar":"وَمِن رَّحْمَتِهِۦ جَعَلَ لَكُمُ ٱلَّيْلَ وَٱلنَّهَارَ لِتَسْكُنُوا۟ فِيهِ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ","en":"And out of His mercy He made for you the night and the day that you may rest therein and [by day] seek from His bounty and [that] perhaps you will be grateful.","tr":"Wamin rahmatihi jaAAala lakumuallayla wannahara litaskunoo feehi walitabtaghoomin fadlihi walaAAallakum tashkuroon","juz":20,"page":394},{"s":28,"a":74,"key":"28:74","ar":"وَيَوْمَ يُنَادِيهِمْ فَيَقُولُ أَيْنَ شُرَكَآءِىَ ٱلَّذِينَ كُنتُمْ تَزْعُمُونَ","en":"And [warn of] the Day He will call them and say, \"Where are My 'partners' which you used to claim?\"","tr":"Wayawma yunadeehim fayaqoolu aynashuraka-iya allatheena kuntum tazAAumoon","juz":20,"page":394},{"s":28,"a":75,"key":"28:75","ar":"وَنَزَعْنَا مِن كُلِّ أُمَّةٍ شَهِيدًا فَقُلْنَا هَاتُوا۟ بُرْهَـٰنَكُمْ فَعَلِمُوٓا۟ أَنَّ ٱلْحَقَّ لِلَّهِ وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَفْتَرُونَ","en":"And We will extract from every nation a witness and say, \"Produce your proof,\" and they will know that the truth belongs to Allāh, and lost from them is that which they used to invent.","tr":"WanazaAAna min kulli ommatinshaheedan faqulna hatoo burhanakumfaAAalimoo anna alhaqqa lillahi wadallaAAanhum ma kanoo yaftaroon","juz":20,"page":394},{"s":28,"a":76,"key":"28:76","ar":"۞ إِنَّ قَـٰرُونَ كَانَ مِن قَوْمِ مُوسَىٰ فَبَغَىٰ عَلَيْهِمْ ۖ وَءَاتَيْنَـٰهُ مِنَ ٱلْكُنُوزِ مَآ إِنَّ مَفَاتِحَهُۥ لَتَنُوٓأُ بِٱلْعُصْبَةِ أُو۟لِى ٱلْقُوَّةِ إِذْ قَالَ لَهُۥ قَوْمُهُۥ لَا تَفْرَحْ ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْفَرِحِينَ","en":"Indeed, Qārūn was from the people of Moses, but he tyrannized them. And We gave him of treasures whose keys would burden a band of strong men; thereupon his people said to him, \"Do not exult. Indeed, Allāh does not like the exultant.","tr":"Inna qaroona kana min qawmimoosa fabagha AAalayhim waataynahumina alkunoozi ma inna mafatihahu latanoo-obilAAusbati olee alquwwati ith qalalahu qawmuhu la tafrah inna Allaha layuhibbu alfariheen","juz":20,"page":394},{"s":28,"a":77,"key":"28:77","ar":"وَٱبْتَغِ فِيمَآ ءَاتَىٰكَ ٱللَّهُ ٱلدَّارَ ٱلْـَٔاخِرَةَ ۖ وَلَا تَنسَ نَصِيبَكَ مِنَ ٱلدُّنْيَا ۖ وَأَحْسِن كَمَآ أَحْسَنَ ٱللَّهُ إِلَيْكَ ۖ وَلَا تَبْغِ ٱلْفَسَادَ فِى ٱلْأَرْضِ ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ ٱلْمُفْسِدِينَ","en":"But seek, through that which Allāh has given you, the home of the Hereafter; and [yet], do not forget your share of the world. And do good as Allāh has done good to you. And desire not corruption in the land. Indeed, Allāh does not like corrupters.\"","tr":"Wabtaghi feema atakaAllahu addara al-akhirata walatansa naseebaka mina addunya waahsinkama ahsana Allahu ilayka wala tabghialfasada fee al-ardi inna Allaha layuhibbu almufsideen","juz":20,"page":394},{"s":28,"a":78,"key":"28:78","ar":"قَالَ إِنَّمَآ أُوتِيتُهُۥ عَلَىٰ عِلْمٍ عِندِىٓ ۚ أَوَلَمْ يَعْلَمْ أَنَّ ٱللَّهَ قَدْ أَهْلَكَ مِن قَبْلِهِۦ مِنَ ٱلْقُرُونِ مَنْ هُوَ أَشَدُّ مِنْهُ قُوَّةً وَأَكْثَرُ جَمْعًا ۚ وَلَا يُسْـَٔلُ عَن ذُنُوبِهِمُ ٱلْمُجْرِمُونَ","en":"He said, \"I was only given it because of knowledge I have.\" Did he not know that Allāh had destroyed before him of generations those who were greater than him in power and greater in accumulation [of wealth]? But the criminals, about their sins, will not be asked.1","tr":"Qala innama ooteetuhu AAalaAAilmin AAindee awa lam yaAAlam anna Allaha qad ahlaka minqablihi mina alqurooni man huwa ashaddu minhu quwwatan waaktharujamAAan wala yus-alu AAan thunoobihimu almujrimoon","juz":20,"page":395},{"s":28,"a":79,"key":"28:79","ar":"فَخَرَجَ عَلَىٰ قَوْمِهِۦ فِى زِينَتِهِۦ ۖ قَالَ ٱلَّذِينَ يُرِيدُونَ ٱلْحَيَوٰةَ ٱلدُّنْيَا يَـٰلَيْتَ لَنَا مِثْلَ مَآ أُوتِىَ قَـٰرُونُ إِنَّهُۥ لَذُو حَظٍّ عَظِيمٍ","en":"So he came out before his people in his adornment. Those who desired the worldly life said, \"Oh, would that we had like what was given to Qārūn. Indeed, he is one of great fortune.\"","tr":"Fakharaja AAala qawmihi fee zeenatihiqala allatheena yureedoona alhayata addunyaya layta lana mithla ma ootiya qaroonuinnahu lathoo haththin AAatheem","juz":20,"page":395},{"s":28,"a":80,"key":"28:80","ar":"وَقَالَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ وَيْلَكُمْ ثَوَابُ ٱللَّهِ خَيْرٌ لِّمَنْ ءَامَنَ وَعَمِلَ صَـٰلِحًا وَلَا يُلَقَّىٰهَآ إِلَّا ٱلصَّـٰبِرُونَ","en":"But those who had been given knowledge said, \"Woe to you! The reward of Allāh is better for he who believes and does righteousness. And none are granted it except the patient.\"","tr":"Waqala allatheena ootooalAAilma waylakum thawabu Allahi khayrun liman amanawaAAamila salihan wala yulaqqahailla assabiroon","juz":20,"page":395},{"s":28,"a":81,"key":"28:81","ar":"فَخَسَفْنَا بِهِۦ وَبِدَارِهِ ٱلْأَرْضَ فَمَا كَانَ لَهُۥ مِن فِئَةٍ يَنصُرُونَهُۥ مِن دُونِ ٱللَّهِ وَمَا كَانَ مِنَ ٱلْمُنتَصِرِينَ","en":"And We caused the earth to swallow him and his home. And there was for him no company to aid him other than Allāh, nor was he of those who [could] defend themselves.","tr":"Fakhasafna bihi wabidarihial-arda fama kana lahu min fi-atin yansuroonahumin dooni Allahi wama kana mina almuntasireen","juz":20,"page":395},{"s":28,"a":82,"key":"28:82","ar":"وَأَصْبَحَ ٱلَّذِينَ تَمَنَّوْا۟ مَكَانَهُۥ بِٱلْأَمْسِ يَقُولُونَ وَيْكَأَنَّ ٱللَّهَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ ۖ لَوْلَآ أَن مَّنَّ ٱللَّهُ عَلَيْنَا لَخَسَفَ بِنَا ۖ وَيْكَأَنَّهُۥ لَا يُفْلِحُ ٱلْكَـٰفِرُونَ","en":"And those who had wished for his position the previous day began to say, \"Oh, how Allāh extends provision to whom He wills of His servants and restricts it! If not that Allāh had conferred favor on us, He would have caused it to swallow us. Oh, how the disbelievers do not succeed!\"","tr":"Waasbaha allatheenatamannaw makanahu bil-amsi yaqooloona waykaannaAllaha yabsutu arrizqa liman yashaomin AAibadihi wayaqdiru lawla an manna AllahuAAalayna lakhasafa bina waykaannahu la yuflihualkafiroon","juz":20,"page":395},{"s":28,"a":83,"key":"28:83","ar":"تِلْكَ ٱلدَّارُ ٱلْـَٔاخِرَةُ نَجْعَلُهَا لِلَّذِينَ لَا يُرِيدُونَ عُلُوًّا فِى ٱلْأَرْضِ وَلَا فَسَادًا ۚ وَٱلْعَـٰقِبَةُ لِلْمُتَّقِينَ","en":"That home of the Hereafter We assign to those who do not desire exaltedness upon the earth or corruption. And the [best] outcome is for the righteous.","tr":"Tilka addaru al-akhiratunajAAaluha lillatheena la yureedoonaAAuluwwan fee al-ardi wala fasadan walAAaqibatulilmuttaqeen","juz":20,"page":395},{"s":28,"a":84,"key":"28:84","ar":"مَن جَآءَ بِٱلْحَسَنَةِ فَلَهُۥ خَيْرٌ مِّنْهَا ۖ وَمَن جَآءَ بِٱلسَّيِّئَةِ فَلَا يُجْزَى ٱلَّذِينَ عَمِلُوا۟ ٱلسَّيِّـَٔاتِ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ","en":"Whoever comes [on the Day of Judgement] with a good deed will have better than it; and whoever comes with an evil deed - then those who did evil deeds will not be recompensed except [as much as] what they used to do.","tr":"Man jaa bilhasanatifalahu khayrun minha waman jaa bissayyi-atifala yujza allatheena AAamiloo assayyi-atiilla ma kanoo yaAAmaloon","juz":20,"page":395},{"s":28,"a":85,"key":"28:85","ar":"إِنَّ ٱلَّذِى فَرَضَ عَلَيْكَ ٱلْقُرْءَانَ لَرَآدُّكَ إِلَىٰ مَعَادٍ ۚ قُل رَّبِّىٓ أَعْلَمُ مَن جَآءَ بِٱلْهُدَىٰ وَمَنْ هُوَ فِى ضَلَـٰلٍ مُّبِينٍ","en":"Indeed, [O Muḥammad], He who imposed upon you the Qur’ān will take you back to a place of return.1 Say, \"My Lord is most knowing of who brings guidance and who is in clear error.\"","tr":"Inna allathee farada AAalaykaalqur-ana laradduka ila maAAadin qulrabbee aAAlamu man jaa bilhuda waman huwafee dalalin mubeen","juz":20,"page":396},{"s":28,"a":86,"key":"28:86","ar":"وَمَا كُنتَ تَرْجُوٓا۟ أَن يُلْقَىٰٓ إِلَيْكَ ٱلْكِتَـٰبُ إِلَّا رَحْمَةً مِّن رَّبِّكَ ۖ فَلَا تَكُونَنَّ ظَهِيرًا لِّلْكَـٰفِرِينَ","en":"And you were not expecting that the Book would be conveyed to you, but [it is] a mercy from your Lord. So do not be an assistant to the disbelievers.1","tr":"Wama kunta tarjoo an yulqailayka alkitabu illa rahmatan min rabbikafala takoonanna thaheeran lilkafireen","juz":20,"page":396},{"s":28,"a":87,"key":"28:87","ar":"وَلَا يَصُدُّنَّكَ عَنْ ءَايَـٰتِ ٱللَّهِ بَعْدَ إِذْ أُنزِلَتْ إِلَيْكَ ۖ وَٱدْعُ إِلَىٰ رَبِّكَ ۖ وَلَا تَكُونَنَّ مِنَ ٱلْمُشْرِكِينَ","en":"And never let them avert you from the verses of Allāh after they have been revealed to you. And invite [people] to your Lord. And never be of those who associate others with Allāh.","tr":"Wala yasuddunnaka AAan ayatiAllahi baAAda ith onzilat ilayka wadAAu ilarabbika wala takoonanna mina almushrikeen","juz":20,"page":396},{"s":28,"a":88,"key":"28:88","ar":"وَلَا تَدْعُ مَعَ ٱللَّهِ إِلَـٰهًا ءَاخَرَ ۘ لَآ إِلَـٰهَ إِلَّا هُوَ ۚ كُلُّ شَىْءٍ هَالِكٌ إِلَّا وَجْهَهُۥ ۚ لَهُ ٱلْحُكْمُ وَإِلَيْهِ تُرْجَعُونَ","en":"And do not invoke with Allāh another deity. There is no deity except Him. Everything will be destroyed except His Face.1 His is the judgement, and to Him you will be returned.","tr":"Wala tadAAu maAAa Allahi ilahanakhara la ilaha illa huwa kullushay-in halikun illa wajhahu lahu alhukmuwa-ilayhi turjaAAoon","juz":20,"page":396},{"s":29,"a":1,"key":"29:1","ar":" الٓمٓ","en":"Alif, Lām, Meem.1","tr":"Alif-lam-meem","juz":20,"page":396},{"s":29,"a":2,"key":"29:2","ar":"أَحَسِبَ ٱلنَّاسُ أَن يُتْرَكُوٓا۟ أَن يَقُولُوٓا۟ ءَامَنَّا وَهُمْ لَا يُفْتَنُونَ","en":"Do the people think that they will be left to say, \"We believe\" and they will not be tried?","tr":"Ahasiba annasu anyutrakoo an yaqooloo amanna wahum layuftanoon","juz":20,"page":396},{"s":29,"a":3,"key":"29:3","ar":"وَلَقَدْ فَتَنَّا ٱلَّذِينَ مِن قَبْلِهِمْ ۖ فَلَيَعْلَمَنَّ ٱللَّهُ ٱلَّذِينَ صَدَقُوا۟ وَلَيَعْلَمَنَّ ٱلْكَـٰذِبِينَ","en":"But We have certainly tried those before them, and Allāh will surely make evident those who are truthful, and He will surely make evident the liars.","tr":"Walaqad fatanna allatheena minqablihim falayaAAlamanna Allahu allatheena sadaqoowalayaAAlamanna alkathibeen","juz":20,"page":396},{"s":29,"a":4,"key":"29:4","ar":"أَمْ حَسِبَ ٱلَّذِينَ يَعْمَلُونَ ٱلسَّيِّـَٔاتِ أَن يَسْبِقُونَا ۚ سَآءَ مَا يَحْكُمُونَ","en":"Or do those who do evil deeds think they can outrun [i.e., escape] Us? Evil is what they judge.","tr":"Am hasiba allatheenayaAAmaloona assayyi-ati an yasbiqoona saama yahkumoon","juz":20,"page":396},{"s":29,"a":5,"key":"29:5","ar":"مَن كَانَ يَرْجُوا۟ لِقَآءَ ٱللَّهِ فَإِنَّ أَجَلَ ٱللَّهِ لَـَٔاتٍ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"Whoever should hope for the meeting with Allāh - indeed, the term [decreed by] Allāh is coming. And He is the Hearing, the Knowing.","tr":"Man kana yarjoo liqaa Allahifa-inna ajala Allahi laatin wahuwa assameeAAualAAaleem","juz":20,"page":396},{"s":29,"a":6,"key":"29:6","ar":"وَمَن جَـٰهَدَ فَإِنَّمَا يُجَـٰهِدُ لِنَفْسِهِۦٓ ۚ إِنَّ ٱللَّهَ لَغَنِىٌّ عَنِ ٱلْعَـٰلَمِينَ","en":"And whoever strives only strives for [the benefit of] himself. Indeed, Allāh is Free from need of the worlds.","tr":"Waman jahada fa-innama yujahidulinafsihi inna Allaha laghaniyyun AAani alAAalameen","juz":20,"page":396},{"s":29,"a":7,"key":"29:7","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَنُكَفِّرَنَّ عَنْهُمْ سَيِّـَٔاتِهِمْ وَلَنَجْزِيَنَّهُمْ أَحْسَنَ ٱلَّذِى كَانُوا۟ يَعْمَلُونَ","en":"And those who believe and do righteous deeds - We will surely remove from them their misdeeds and will surely reward them according to the best of what they used to do.","tr":"Wallatheena amanoowaAAamiloo assalihati lanukaffirannaAAanhum sayyi-atihim walanajziyannahum ahsana allatheekanoo yaAAmaloon","juz":20,"page":397},{"s":29,"a":8,"key":"29:8","ar":"وَوَصَّيْنَا ٱلْإِنسَـٰنَ بِوَٰلِدَيْهِ حُسْنًا ۖ وَإِن جَـٰهَدَاكَ لِتُشْرِكَ بِى مَا لَيْسَ لَكَ بِهِۦ عِلْمٌ فَلَا تُطِعْهُمَآ ۚ إِلَىَّ مَرْجِعُكُمْ فَأُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ","en":"And We have enjoined upon man goodness to parents. But if they endeavor to make you associate with Me that of which you have no knowledge,1 do not obey them. To Me is your return, and I will inform you about what you used to do.","tr":"Wawassayna al-insana biwalidayhihusnan wa-in jahadaka litushrika bee malaysa laka bihi AAilmun fala tutiAAhumailayya marjiAAukum faonabbi-okum bima kuntum taAAmaloon","juz":20,"page":397},{"s":29,"a":9,"key":"29:9","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَنُدْخِلَنَّهُمْ فِى ٱلصَّـٰلِحِينَ","en":"And those who believe and do righteous deeds - We will surely admit them among the righteous [into Paradise].","tr":"Wallatheena amanoowaAAamiloo assalihati lanudkhilannahum feeassaliheen","juz":20,"page":397},{"s":29,"a":10,"key":"29:10","ar":"وَمِنَ ٱلنَّاسِ مَن يَقُولُ ءَامَنَّا بِٱللَّهِ فَإِذَآ أُوذِىَ فِى ٱللَّهِ جَعَلَ فِتْنَةَ ٱلنَّاسِ كَعَذَابِ ٱللَّهِ وَلَئِن جَآءَ نَصْرٌ مِّن رَّبِّكَ لَيَقُولُنَّ إِنَّا كُنَّا مَعَكُمْ ۚ أَوَلَيْسَ ٱللَّهُ بِأَعْلَمَ بِمَا فِى صُدُورِ ٱلْعَـٰلَمِينَ","en":"And of the people are some who say, \"We believe in Allāh,\" but when one [of them] is harmed for [the cause of] Allāh, he considers the trial [i.e., harm] of the people as [if it were] the punishment of Allāh. But if victory comes from your Lord, they say, \"Indeed, We were with you.\" Is not Allāh most knowing of what is within the breasts of the worlds [i.e., all creatures]?","tr":"Wamina annasi man yaqoolu amannabillahi fa-itha oothiya fee AllahijaAAala fitnata annasi kaAAathabi Allahiwala-in jaa nasrun min rabbika layaqoolunna innakunna maAAakum awa laysa Allahu bi-aAAlama bimafee sudoori alAAalameen","juz":20,"page":397},{"s":29,"a":11,"key":"29:11","ar":"وَلَيَعْلَمَنَّ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَلَيَعْلَمَنَّ ٱلْمُنَـٰفِقِينَ","en":"And Allāh will surely make evident those who believe, and He will surely make evident the hypocrites.","tr":"WalayaAAlamanna Allahu allatheenaamanoo walayaAAlamanna almunafiqeen","juz":20,"page":397},{"s":29,"a":12,"key":"29:12","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوا۟ ٱتَّبِعُوا۟ سَبِيلَنَا وَلْنَحْمِلْ خَطَـٰيَـٰكُمْ وَمَا هُم بِحَـٰمِلِينَ مِنْ خَطَـٰيَـٰهُم مِّن شَىْءٍ ۖ إِنَّهُمْ لَكَـٰذِبُونَ","en":"And those who disbelieve say to those who believe, \"Follow our way, and we will carry your sins.\"1 But they will not carry anything of their sins. Indeed, they are liars.","tr":"Waqala allatheena kafaroolillatheena amanoo ittabiAAoo sabeelanawalnahmil khatayakum wama hum bihamileenamin khatayahum min shay-in innahum lakathiboon","juz":20,"page":397},{"s":29,"a":13,"key":"29:13","ar":"وَلَيَحْمِلُنَّ أَثْقَالَهُمْ وَأَثْقَالًا مَّعَ أَثْقَالِهِمْ ۖ وَلَيُسْـَٔلُنَّ يَوْمَ ٱلْقِيَـٰمَةِ عَمَّا كَانُوا۟ يَفْتَرُونَ","en":"But they will surely carry their [own] burdens and [other] burdens along with their burdens,1 and they will surely be questioned on the Day of Resurrection about what they used to invent.","tr":"Walayahmilunna athqalahumwaathqalan maAAa athqalihim walayus-alunna yawmaalqiyamati AAamma kanoo yaftaroon","juz":20,"page":397},{"s":29,"a":14,"key":"29:14","ar":"وَلَقَدْ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦ فَلَبِثَ فِيهِمْ أَلْفَ سَنَةٍ إِلَّا خَمْسِينَ عَامًا فَأَخَذَهُمُ ٱلطُّوفَانُ وَهُمْ ظَـٰلِمُونَ","en":"And We certainly sent Noah to his people, and he remained among them a thousand years minus fifty years, and the flood seized them while they were wrongdoers.","tr":"Walaqad arsalna noohan ilaqawmihi falabitha feehim alfa sanatin illa khamseena AAamanfaakhathahumu attoofanu wahum thalimoon","juz":20,"page":397},{"s":29,"a":15,"key":"29:15","ar":"فَأَنجَيْنَـٰهُ وَأَصْحَـٰبَ ٱلسَّفِينَةِ وَجَعَلْنَـٰهَآ ءَايَةً لِّلْعَـٰلَمِينَ","en":"But We saved him and the companions of the ship, and We made it1 a sign for the worlds.","tr":"Faanjaynahu waas-haba assafeenatiwajaAAalnaha ayatan lilAAalameen","juz":20,"page":398},{"s":29,"a":16,"key":"29:16","ar":"وَإِبْرَٰهِيمَ إِذْ قَالَ لِقَوْمِهِ ٱعْبُدُوا۟ ٱللَّهَ وَٱتَّقُوهُ ۖ ذَٰلِكُمْ خَيْرٌ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ","en":"And [We sent] Abraham, when he said to his people, \"Worship Allāh and fear Him. That is best for you, if you should know.","tr":"Wa-ibraheema ith qalaliqawmihi oAAbudoo Allaha wattaqoohu thalikumkhayrun lakum in kuntum taAAlamoon","juz":20,"page":398},{"s":29,"a":17,"key":"29:17","ar":"إِنَّمَا تَعْبُدُونَ مِن دُونِ ٱللَّهِ أَوْثَـٰنًا وَتَخْلُقُونَ إِفْكًا ۚ إِنَّ ٱلَّذِينَ تَعْبُدُونَ مِن دُونِ ٱللَّهِ لَا يَمْلِكُونَ لَكُمْ رِزْقًا فَٱبْتَغُوا۟ عِندَ ٱللَّهِ ٱلرِّزْقَ وَٱعْبُدُوهُ وَٱشْكُرُوا۟ لَهُۥٓ ۖ إِلَيْهِ تُرْجَعُونَ","en":"You only worship, besides Allāh, idols, and you produce a falsehood. Indeed, those you worship besides Allāh do not possess for you [the power of] provision. So seek from Allāh provision and worship Him and be grateful to Him. To Him you will be returned.\"","tr":"Innama taAAbudoona min dooni Allahiawthanan watakhluqoona ifkan inna allatheenataAAbudoona min dooni Allahi la yamlikoona lakumrizqan fabtaghoo AAinda Allahi arrizqa waAAbudoohuwashkuroo lahu ilayhi turjaAAoon","juz":20,"page":398},{"s":29,"a":18,"key":"29:18","ar":"وَإِن تُكَذِّبُوا۟ فَقَدْ كَذَّبَ أُمَمٌ مِّن قَبْلِكُمْ ۖ وَمَا عَلَى ٱلرَّسُولِ إِلَّا ٱلْبَلَـٰغُ ٱلْمُبِينُ","en":"And if you [people] deny [the message] - already nations before you have denied. And there is not upon the Messenger except [the duty of] clear notification.1","tr":"Wa-in tukaththiboo faqad kaththabaomamun min qablikum wama AAala arrasooliilla albalaghu almubeen","juz":20,"page":398},{"s":29,"a":19,"key":"29:19","ar":"أَوَلَمْ يَرَوْا۟ كَيْفَ يُبْدِئُ ٱللَّهُ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥٓ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌ","en":"Have they not considered how Allāh begins creation and then repeats it? Indeed that, for Allāh, is easy.","tr":"Awa lam yaraw kayfa yubdi-o Allahualkhalqa thumma yuAAeeduhu inna thalika AAala Allahiyaseer","juz":20,"page":398},{"s":29,"a":20,"key":"29:20","ar":"قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ بَدَأَ ٱلْخَلْقَ ۚ ثُمَّ ٱللَّهُ يُنشِئُ ٱلنَّشْأَةَ ٱلْـَٔاخِرَةَ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Say, [O Muḥammad], \"Travel through the land and observe how He began creation. Then Allāh will produce the final creation [i.e., development]. Indeed Allāh, over all things, is competent.\"","tr":"Qul seeroo fee al-ardi fanthurookayfa badaa alkhalqa thumma Allahu yunshi-o annash-ataal-akhirata inna Allaha AAala kulli shay-inqadeer","juz":20,"page":398},{"s":29,"a":21,"key":"29:21","ar":"يُعَذِّبُ مَن يَشَآءُ وَيَرْحَمُ مَن يَشَآءُ ۖ وَإِلَيْهِ تُقْلَبُونَ","en":"He punishes whom He wills and has mercy upon whom He wills, and to Him you will be returned.","tr":"YuAAaththibu man yashao wayarhamuman yashao wa-ilayhi tuqlaboon","juz":20,"page":398},{"s":29,"a":22,"key":"29:22","ar":"وَمَآ أَنتُم بِمُعْجِزِينَ فِى ٱلْأَرْضِ وَلَا فِى ٱلسَّمَآءِ ۖ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّ وَلَا نَصِيرٍ","en":"And you will not cause failure [to Allāh] upon the earth or in the heaven. And you have not other than Allāh any protector or any helper.","tr":"Wama antum bimuAAjizeena fee al-ardiwala fee assama-i wama lakum mindooni Allahi min waliyyin wala naseer","juz":20,"page":398},{"s":29,"a":23,"key":"29:23","ar":"وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَـٰتِ ٱللَّهِ وَلِقَآئِهِۦٓ أُو۟لَـٰٓئِكَ يَئِسُوا۟ مِن رَّحْمَتِى وَأُو۟لَـٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌ","en":"And the ones who disbelieve in the signs of Allāh and the meeting with Him - those have despaired of My mercy, and they will have a painful punishment.","tr":"Wallatheena kafaroo bi-ayatiAllahi waliqa-ihi ola-ika ya-isoo min rahmateewaola-ika lahum AAathabun aleem","juz":20,"page":398},{"s":29,"a":24,"key":"29:24","ar":"فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوا۟ ٱقْتُلُوهُ أَوْ حَرِّقُوهُ فَأَنجَىٰهُ ٱللَّهُ مِنَ ٱلنَّارِ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يُؤْمِنُونَ","en":"And the answer of his [i.e., Abraham's] people was not but that they said, \"Kill him or burn him,\" but Allāh saved him from the fire. Indeed in that are signs for a people who believe.","tr":"Fama kana jawabaqawmihi illa an qaloo oqtuloohu aw harriqoohufaanjahu Allahu mina annari inna feethalika laayatin liqawmin yu/minoon","juz":20,"page":399},{"s":29,"a":25,"key":"29:25","ar":"وَقَالَ إِنَّمَا ٱتَّخَذْتُم مِّن دُونِ ٱللَّهِ أَوْثَـٰنًا مَّوَدَّةَ بَيْنِكُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ ثُمَّ يَوْمَ ٱلْقِيَـٰمَةِ يَكْفُرُ بَعْضُكُم بِبَعْضٍ وَيَلْعَنُ بَعْضُكُم بَعْضًا وَمَأْوَىٰكُمُ ٱلنَّارُ وَمَا لَكُم مِّن نَّـٰصِرِينَ","en":"And [Abraham] said, \"You have only taken, other than Allāh, idols as [a bond of] affection among you in worldly life. Then on the Day of Resurrection you will deny one another and curse one another, and your refuge will be the Fire, and you will not have any helpers.\"","tr":"Waqala innama ittakhathtummin dooni Allahi awthanan mawaddata baynikum fee alhayatiaddunya thumma yawma alqiyamati yakfurubaAAdukum bibaAAdin wayalAAanu baAAdukumbaAAdan wama-wakumu annaru wamalakum min nasireen","juz":20,"page":399},{"s":29,"a":26,"key":"29:26","ar":"۞ فَـَٔامَنَ لَهُۥ لُوطٌ ۘ وَقَالَ إِنِّى مُهَاجِرٌ إِلَىٰ رَبِّىٓ ۖ إِنَّهُۥ هُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"And Lot believed him. [Abraham] said, \"Indeed, I will emigrate to [the service of] my Lord. Indeed, He is the Exalted in Might, the Wise.\"","tr":"Faamana lahu lootun waqalainnee muhajirun ila rabbee innahu huwa alAAazeezualhakeem","juz":20,"page":399},{"s":29,"a":27,"key":"29:27","ar":"وَوَهَبْنَا لَهُۥٓ إِسْحَـٰقَ وَيَعْقُوبَ وَجَعَلْنَا فِى ذُرِّيَّتِهِ ٱلنُّبُوَّةَ وَٱلْكِتَـٰبَ وَءَاتَيْنَـٰهُ أَجْرَهُۥ فِى ٱلدُّنْيَا ۖ وَإِنَّهُۥ فِى ٱلْـَٔاخِرَةِ لَمِنَ ٱلصَّـٰلِحِينَ","en":"And We gave to him Isaac and Jacob and placed in his descendants prophethood and scripture. And We gave him his reward in this world, and indeed, he is in the Hereafter among the righteous.","tr":"Wawahabna lahu ishaqawayaAAqooba wajaAAalna fee thurriyyatihi annubuwwatawalkitaba waataynahu ajrahu fee addunyawa-innahu fee al-akhirati lamina assaliheen","juz":20,"page":399},{"s":29,"a":28,"key":"29:28","ar":"وَلُوطًا إِذْ قَالَ لِقَوْمِهِۦٓ إِنَّكُمْ لَتَأْتُونَ ٱلْفَـٰحِشَةَ مَا سَبَقَكُم بِهَا مِنْ أَحَدٍ مِّنَ ٱلْعَـٰلَمِينَ","en":"And [mention] Lot, when he said to his people, \"Indeed, you commit such immorality as no one has preceded you with from among the worlds.","tr":"Walootan ith qalaliqawmihi innakum lata/toona alfahishata masabaqakum biha min ahadin mina alAAalameen","juz":20,"page":399},{"s":29,"a":29,"key":"29:29","ar":"أَئِنَّكُمْ لَتَأْتُونَ ٱلرِّجَالَ وَتَقْطَعُونَ ٱلسَّبِيلَ وَتَأْتُونَ فِى نَادِيكُمُ ٱلْمُنكَرَ ۖ فَمَا كَانَ جَوَابَ قَوْمِهِۦٓ إِلَّآ أَن قَالُوا۟ ٱئْتِنَا بِعَذَابِ ٱللَّهِ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ","en":"Indeed, you approach men and obstruct the road1 and commit in your meetings [every] evil.\" And the answer of his people was not but that they said, \"Bring us the punishment of Allāh, if you should be of the truthful.\"","tr":"A-innakum lata/toona arrijalawataqtaAAoona assabeela wata/toona fee nadeekumualmunkara fama kana jawaba qawmihi illaan qaloo i/tina biAAathabi Allahi inkunta mina assadiqeen","juz":20,"page":399},{"s":29,"a":30,"key":"29:30","ar":"قَالَ رَبِّ ٱنصُرْنِى عَلَى ٱلْقَوْمِ ٱلْمُفْسِدِينَ","en":"He said, \"My Lord, support me against the corrupting people.\"","tr":"Qala rabbi onsurnee AAalaalqawmi almufsideen","juz":20,"page":399},{"s":29,"a":31,"key":"29:31","ar":"وَلَمَّا جَآءَتْ رُسُلُنَآ إِبْرَٰهِيمَ بِٱلْبُشْرَىٰ قَالُوٓا۟ إِنَّا مُهْلِكُوٓا۟ أَهْلِ هَـٰذِهِ ٱلْقَرْيَةِ ۖ إِنَّ أَهْلَهَا كَانُوا۟ ظَـٰلِمِينَ","en":"And when Our messengers [i.e., angels] came to Abraham with the good tidings,1 they said, \"Indeed, we will destroy the people of that [i.e., Lot's] city. Indeed, its people have been wrongdoers.\"","tr":"Walamma jaat rusulunaibraheema bilbushra qaloo innamuhlikoo ahli hathihi alqaryati inna ahlaha kanoothalimeen","juz":20,"page":400},{"s":29,"a":32,"key":"29:32","ar":"قَالَ إِنَّ فِيهَا لُوطًا ۚ قَالُوا۟ نَحْنُ أَعْلَمُ بِمَن فِيهَا ۖ لَنُنَجِّيَنَّهُۥ وَأَهْلَهُۥٓ إِلَّا ٱمْرَأَتَهُۥ كَانَتْ مِنَ ٱلْغَـٰبِرِينَ","en":"[Abraham] said, \"Indeed, within it is Lot.\" They said, \"We are more knowing of who is within it. We will surely save him and his family, except his wife. She is to be of those who remain behind.\"","tr":"Qala inna feeha lootanqaloo nahnu aAAlamu biman feehalanunajjiyannahu waahlahu illa imraatahu kanat minaalghabireen","juz":20,"page":400},{"s":29,"a":33,"key":"29:33","ar":"وَلَمَّآ أَن جَآءَتْ رُسُلُنَا لُوطًا سِىٓءَ بِهِمْ وَضَاقَ بِهِمْ ذَرْعًا وَقَالُوا۟ لَا تَخَفْ وَلَا تَحْزَنْ ۖ إِنَّا مُنَجُّوكَ وَأَهْلَكَ إِلَّا ٱمْرَأَتَكَ كَانَتْ مِنَ ٱلْغَـٰبِرِينَ","en":"And when Our messengers [i.e., angels] came to Lot, he was distressed for them and felt for them great discomfort.1 They said, \"Fear not, nor grieve. Indeed, we will save you and your family, except your wife; she is to be of those who remain behind.","tr":"Walamma an jaat rusulunalootan see-a bihim wadaqa bihim tharAAan waqaloola takhaf wala tahzan inna munajjookawaahlaka illa imraataka kanat mina alghabireen","juz":20,"page":400},{"s":29,"a":34,"key":"29:34","ar":"إِنَّا مُنزِلُونَ عَلَىٰٓ أَهْلِ هَـٰذِهِ ٱلْقَرْيَةِ رِجْزًا مِّنَ ٱلسَّمَآءِ بِمَا كَانُوا۟ يَفْسُقُونَ","en":"Indeed, we will bring down on the people of this city punishment from the sky because they have been defiantly disobedient.\"","tr":"Inna munziloona AAala ahli hathihialqaryati rijzan mina assama-i bima kanooyafsuqoon","juz":20,"page":400},{"s":29,"a":35,"key":"29:35","ar":"وَلَقَد تَّرَكْنَا مِنْهَآ ءَايَةًۢ بَيِّنَةً لِّقَوْمٍ يَعْقِلُونَ","en":"And We have certainly left of it a sign as clear evidence for a people who use reason.","tr":"Walaqad tarakna minha ayatanbayyinatan liqawmin yaAAqiloon","juz":20,"page":400},{"s":29,"a":36,"key":"29:36","ar":"وَإِلَىٰ مَدْيَنَ أَخَاهُمْ شُعَيْبًا فَقَالَ يَـٰقَوْمِ ٱعْبُدُوا۟ ٱللَّهَ وَٱرْجُوا۟ ٱلْيَوْمَ ٱلْـَٔاخِرَ وَلَا تَعْثَوْا۟ فِى ٱلْأَرْضِ مُفْسِدِينَ","en":"And to Madyan [We sent] their brother Shuʿayb, and he said, \"O my people, worship Allāh and expect the Last Day and do not commit abuse on the earth, spreading corruption.\"","tr":"Wa-ila madyana akhahumshuAAayban faqala ya qawmi oAAbudoo Allahawarjoo alyawma al-akhira wala taAAthaw feeal-ardi mufsideen","juz":20,"page":400},{"s":29,"a":37,"key":"29:37","ar":"فَكَذَّبُوهُ فَأَخَذَتْهُمُ ٱلرَّجْفَةُ فَأَصْبَحُوا۟ فِى دَارِهِمْ جَـٰثِمِينَ","en":"But they denied him, so the earthquake seized them, and they became within their home [corpses] fallen prone.","tr":"Fakaththaboohu faakhathat-humuarrajfatu faasbahoo fee darihim jathimeen","juz":20,"page":400},{"s":29,"a":38,"key":"29:38","ar":"وَعَادًا وَثَمُودَا۟ وَقَد تَّبَيَّنَ لَكُم مِّن مَّسَـٰكِنِهِمْ ۖ وَزَيَّنَ لَهُمُ ٱلشَّيْطَـٰنُ أَعْمَـٰلَهُمْ فَصَدَّهُمْ عَنِ ٱلسَّبِيلِ وَكَانُوا۟ مُسْتَبْصِرِينَ","en":"And [We destroyed] ʿAad and Thamūd, and it has become clear to you from their [ruined] dwellings. And Satan had made pleasing to them their deeds and averted them from the path, and they were endowed with perception.","tr":"WaAAadan wathamooda waqad tabayyanalakum min masakinihim wazayyana lahumu ashshaytanuaAAmalahum fasaddahum AAani assabeeli wakanoomustabsireen","juz":20,"page":400},{"s":29,"a":39,"key":"29:39","ar":"وَقَـٰرُونَ وَفِرْعَوْنَ وَهَـٰمَـٰنَ ۖ وَلَقَدْ جَآءَهُم مُّوسَىٰ بِٱلْبَيِّنَـٰتِ فَٱسْتَكْبَرُوا۟ فِى ٱلْأَرْضِ وَمَا كَانُوا۟ سَـٰبِقِينَ","en":"And [We destroyed] Qārūn and Pharaoh and Hāmān. And Moses had already come to them with clear evidences, and they were arrogant in the land, but they were not outrunners [of Our punishment].","tr":"Waqaroona wafirAAawna wahamanawalaqad jaahum moosa bilbayyinati fastakbaroofee al-ardi wama kanoo sabiqeen","juz":20,"page":401},{"s":29,"a":40,"key":"29:40","ar":"فَكُلًّا أَخَذْنَا بِذَنۢبِهِۦ ۖ فَمِنْهُم مَّنْ أَرْسَلْنَا عَلَيْهِ حَاصِبًا وَمِنْهُم مَّنْ أَخَذَتْهُ ٱلصَّيْحَةُ وَمِنْهُم مَّنْ خَسَفْنَا بِهِ ٱلْأَرْضَ وَمِنْهُم مَّنْ أَغْرَقْنَا ۚ وَمَا كَانَ ٱللَّهُ لِيَظْلِمَهُمْ وَلَـٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ","en":"So each We seized for his sin; and among them were those upon whom We sent a storm of stones, and among them were those who were seized by the blast [from the sky], and among them were those whom We caused the earth to swallow, and among them were those whom We drowned. And Allāh would not have wronged them, but it was they who were wronging themselves.","tr":"Fakullan akhathna bithanbihifaminhum man arsalna AAalayhi hasiban waminhum manakhathat-hu assayhatu waminhum mankhasafna bihi al-arda waminhum man aghraqnawama kana Allahu liyathlimahumwalakin kanoo anfusahum yathlimoon","juz":20,"page":401},{"s":29,"a":41,"key":"29:41","ar":"مَثَلُ ٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ أَوْلِيَآءَ كَمَثَلِ ٱلْعَنكَبُوتِ ٱتَّخَذَتْ بَيْتًا ۖ وَإِنَّ أَوْهَنَ ٱلْبُيُوتِ لَبَيْتُ ٱلْعَنكَبُوتِ ۖ لَوْ كَانُوا۟ يَعْلَمُونَ","en":"The example of those who take allies other than Allāh is like that of the spider who takes [i.e., constructs] a home. And indeed, the weakest of homes is the home of the spider, if they only knew.","tr":"Mathalu allatheena ittakhathoomin dooni Allahi awliyaa kamathali alAAankabootiittakhathat baytan wa-inna awhana albuyooti labaytualAAankabooti law kanoo yaAAlamoon","juz":20,"page":401},{"s":29,"a":42,"key":"29:42","ar":"إِنَّ ٱللَّهَ يَعْلَمُ مَا يَدْعُونَ مِن دُونِهِۦ مِن شَىْءٍ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Indeed, Allāh knows whatever thing they call upon1 other than Him. And He is the Exalted in Might, the Wise.","tr":"Inna Allaha yaAAlamu mayadAAoona min doonihi min shay-in wahuwa alAAazeezu alhakeem","juz":20,"page":401},{"s":29,"a":43,"key":"29:43","ar":"وَتِلْكَ ٱلْأَمْثَـٰلُ نَضْرِبُهَا لِلنَّاسِ ۖ وَمَا يَعْقِلُهَآ إِلَّا ٱلْعَـٰلِمُونَ","en":"And these examples We present to the people, but none will understand them except those of knowledge.","tr":"Watilka al-amthalu nadribuhalinnasi wama yaAAqiluha illaalAAalimoon","juz":20,"page":401},{"s":29,"a":44,"key":"29:44","ar":"خَلَقَ ٱللَّهُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّلْمُؤْمِنِينَ","en":"Allāh created the heavens and the earth in truth. Indeed in that is a sign for the believers.","tr":"Khalaqa Allahu assamawatiwal-arda bilhaqqi inna fee thalikalaayatan lilmu-mineen","juz":20,"page":401},{"s":29,"a":45,"key":"29:45","ar":"ٱتْلُ مَآ أُوحِىَ إِلَيْكَ مِنَ ٱلْكِتَـٰبِ وَأَقِمِ ٱلصَّلَوٰةَ ۖ إِنَّ ٱلصَّلَوٰةَ تَنْهَىٰ عَنِ ٱلْفَحْشَآءِ وَٱلْمُنكَرِ ۗ وَلَذِكْرُ ٱللَّهِ أَكْبَرُ ۗ وَٱللَّهُ يَعْلَمُ مَا تَصْنَعُونَ","en":"Recite, [O Muḥammad], what has been revealed to you of the Book and establish prayer. Indeed, prayer prohibits immorality and wrongdoing, and the remembrance of Allāh is greater. And Allāh knows that which you do.","tr":"Otlu ma oohiya ilayka minaalkitabi waaqimi assalata inna assalatatanha AAani alfahsha-i walmunkariwalathikru Allahi akbaru wallahuyaAAlamu ma tasnaAAoon","juz":20,"page":401},{"s":29,"a":46,"key":"29:46","ar":"۞ وَلَا تُجَـٰدِلُوٓا۟ أَهْلَ ٱلْكِتَـٰبِ إِلَّا بِٱلَّتِى هِىَ أَحْسَنُ إِلَّا ٱلَّذِينَ ظَلَمُوا۟ مِنْهُمْ ۖ وَقُولُوٓا۟ ءَامَنَّا بِٱلَّذِىٓ أُنزِلَ إِلَيْنَا وَأُنزِلَ إِلَيْكُمْ وَإِلَـٰهُنَا وَإِلَـٰهُكُمْ وَٰحِدٌ وَنَحْنُ لَهُۥ مُسْلِمُونَ","en":"And do not argue with the People of the Scripture except in a way that is best, except for those who commit injustice among them, and say, \"We believe in that which has been revealed to us and revealed to you. And our God and your God is one; and we are Muslims [in submission] to Him.\"","tr":"Wala tujadiloo ahla alkitabiilla billatee hiya ahsanu illa allatheenathalamoo minhum waqooloo amanna billatheeonzila ilayna waonzila ilaykum wa-ilahunawa-ilahukum wahidun wanahnu lahu muslimoon","juz":21,"page":402},{"s":29,"a":47,"key":"29:47","ar":"وَكَذَٰلِكَ أَنزَلْنَآ إِلَيْكَ ٱلْكِتَـٰبَ ۚ فَٱلَّذِينَ ءَاتَيْنَـٰهُمُ ٱلْكِتَـٰبَ يُؤْمِنُونَ بِهِۦ ۖ وَمِنْ هَـٰٓؤُلَآءِ مَن يُؤْمِنُ بِهِۦ ۚ وَمَا يَجْحَدُ بِـَٔايَـٰتِنَآ إِلَّا ٱلْكَـٰفِرُونَ","en":"And thus We have sent down to you the Book [i.e., the Qur’ān]. And those to whom We [previously] gave the Scripture believe in it. And among these [people of Makkah] are those who believe in it. And none reject Our verses except the disbelievers.","tr":"Wakathalika anzalna ilaykaalkitaba fallatheena ataynahumualkitaba yu/minoona bihi wamin haola-i manyu/minu bihi wama yajhadu bi-ayatinailla alkafiroon","juz":21,"page":402},{"s":29,"a":48,"key":"29:48","ar":"وَمَا كُنتَ تَتْلُوا۟ مِن قَبْلِهِۦ مِن كِتَـٰبٍ وَلَا تَخُطُّهُۥ بِيَمِينِكَ ۖ إِذًا لَّٱرْتَابَ ٱلْمُبْطِلُونَ","en":"And you did not recite before it any scripture, nor did you inscribe one with your right hand. Then [i.e., otherwise] the falsifiers would have had [cause for] doubt.","tr":"Wama kunta tatloo min qablihi min kitabinwala takhuttuhu biyameenika ithan lartabaalmubtiloon","juz":21,"page":402},{"s":29,"a":49,"key":"29:49","ar":"بَلْ هُوَ ءَايَـٰتٌۢ بَيِّنَـٰتٌ فِى صُدُورِ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ ۚ وَمَا يَجْحَدُ بِـَٔايَـٰتِنَآ إِلَّا ٱلظَّـٰلِمُونَ","en":"Rather, it [i.e., the Qur’ān] is distinct verses [preserved] within the breasts of those who have been given knowledge. And none reject Our verses except the wrongdoers.","tr":"Bal huwa ayatun bayyinatunfee sudoori allatheena ootoo alAAilma wamayajhadu bi-ayatina illa aththalimoon","juz":21,"page":402},{"s":29,"a":50,"key":"29:50","ar":"وَقَالُوا۟ لَوْلَآ أُنزِلَ عَلَيْهِ ءَايَـٰتٌ مِّن رَّبِّهِۦ ۖ قُلْ إِنَّمَا ٱلْـَٔايَـٰتُ عِندَ ٱللَّهِ وَإِنَّمَآ أَنَا۠ نَذِيرٌ مُّبِينٌ","en":"But they say, \"Why are not signs sent down to him from his Lord?\" Say, \"The signs are only with Allāh, and I am only a clear warner.\"","tr":"Waqaloo lawla onzila AAalayhi ayatunmin rabbihi qul innama al-ayatu AAinda Allahiwa-innama ana natheerun mubeen","juz":21,"page":402},{"s":29,"a":51,"key":"29:51","ar":"أَوَلَمْ يَكْفِهِمْ أَنَّآ أَنزَلْنَا عَلَيْكَ ٱلْكِتَـٰبَ يُتْلَىٰ عَلَيْهِمْ ۚ إِنَّ فِى ذَٰلِكَ لَرَحْمَةً وَذِكْرَىٰ لِقَوْمٍ يُؤْمِنُونَ","en":"And is it not sufficient for them that We revealed to you the Book [i.e., the Qur’ān] which is recited to them? Indeed in that is a mercy and reminder for a people who believe.","tr":"Awa lam yakfihim anna anzalnaAAalayka alkitaba yutla AAalayhim inna fee thalikalarahmatan wathikra liqawmin yu/minoon","juz":21,"page":402},{"s":29,"a":52,"key":"29:52","ar":"قُلْ كَفَىٰ بِٱللَّهِ بَيْنِى وَبَيْنَكُمْ شَهِيدًا ۖ يَعْلَمُ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱلَّذِينَ ءَامَنُوا۟ بِٱلْبَـٰطِلِ وَكَفَرُوا۟ بِٱللَّهِ أُو۟لَـٰٓئِكَ هُمُ ٱلْخَـٰسِرُونَ","en":"Say, \"Sufficient is Allāh between me and you as Witness. He knows what is in the heavens and earth. And they who have believed in falsehood and disbelieved in Allāh - it is those who are the losers.\"","tr":"Qul kafa billahibaynee wabaynakum shaheedan yaAAlamu ma fee assamawatiwal-ardi wallatheena amanoobilbatili wakafaroo billahi ola-ikahumu alkhasiroon","juz":21,"page":402},{"s":29,"a":53,"key":"29:53","ar":"وَيَسْتَعْجِلُونَكَ بِٱلْعَذَابِ ۚ وَلَوْلَآ أَجَلٌ مُّسَمًّى لَّجَآءَهُمُ ٱلْعَذَابُ وَلَيَأْتِيَنَّهُم بَغْتَةً وَهُمْ لَا يَشْعُرُونَ","en":"And they urge you to hasten the punishment. And if not for [the decree of] a specified term, punishment would have reached them. But it will surely come to them suddenly while they perceive not.","tr":"WayastaAAjiloonaka bilAAathabiwalawla ajalun musamman lajaahumu alAAathabuwalaya/tiyannahum baghtatan wahum la yashAAuroon","juz":21,"page":403},{"s":29,"a":54,"key":"29:54","ar":"يَسْتَعْجِلُونَكَ بِٱلْعَذَابِ وَإِنَّ جَهَنَّمَ لَمُحِيطَةٌۢ بِٱلْكَـٰفِرِينَ","en":"They urge you to hasten the punishment. And indeed, Hell will be encompassing of the disbelievers","tr":"YastaAAjiloonaka bilAAathabiwa-inna jahannama lamuheetatun bilkafireen","juz":21,"page":403},{"s":29,"a":55,"key":"29:55","ar":"يَوْمَ يَغْشَىٰهُمُ ٱلْعَذَابُ مِن فَوْقِهِمْ وَمِن تَحْتِ أَرْجُلِهِمْ وَيَقُولُ ذُوقُوا۟ مَا كُنتُمْ تَعْمَلُونَ","en":"On the Day the punishment will cover them from above them and from below their feet and it is said, \"Taste [the result of] what you used to do.\"","tr":"Yawma yaghshahumu alAAathabumin fawqihim wamin tahti arjulihim wayaqoolu thooqooma kuntum taAAmaloon","juz":21,"page":403},{"s":29,"a":56,"key":"29:56","ar":"يَـٰعِبَادِىَ ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ أَرْضِى وَٰسِعَةٌ فَإِيَّـٰىَ فَٱعْبُدُونِ","en":"O My servants who have believed, indeed My earth is spacious, so worship only Me.","tr":"Ya AAibadiya allatheenaamanoo inna ardee wasiAAatun fa-iyyayafaAAbudoon","juz":21,"page":403},{"s":29,"a":57,"key":"29:57","ar":"كُلُّ نَفْسٍ ذَآئِقَةُ ٱلْمَوْتِ ۖ ثُمَّ إِلَيْنَا تُرْجَعُونَ","en":"Every soul will taste death. Then to Us will you be returned.","tr":"Kullu nafsin tha-iqatu almawti thummailayna turjaAAoon","juz":21,"page":403},{"s":29,"a":58,"key":"29:58","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَنُبَوِّئَنَّهُم مِّنَ ٱلْجَنَّةِ غُرَفًا تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا ۚ نِعْمَ أَجْرُ ٱلْعَـٰمِلِينَ","en":"And those who have believed and done righteous deeds - We will surely assign to them of Paradise [elevated] chambers beneath which rivers flow, wherein they abide eternally. Excellent is the reward of the [righteous] workers","tr":"Wallatheena amanoowaAAamiloo assalihati lanubawwi-annahummina aljannati ghurafan tajree min tahtiha al-anharukhalideena feeha niAAma ajru alAAamileen","juz":21,"page":403},{"s":29,"a":59,"key":"29:59","ar":"ٱلَّذِينَ صَبَرُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ","en":"Who have been patient and upon their Lord rely.","tr":"Allatheena sabaroo waAAalarabbihim yatawakkaloon","juz":21,"page":403},{"s":29,"a":60,"key":"29:60","ar":"وَكَأَيِّن مِّن دَآبَّةٍ لَّا تَحْمِلُ رِزْقَهَا ٱللَّهُ يَرْزُقُهَا وَإِيَّاكُمْ ۚ وَهُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"And how many a creature carries not its [own] provision. Allāh provides for it and for you. And He is the Hearing, the Knowing.","tr":"Wakaayyin min dabbatin la tahmilurizqaha Allahu yarzuquha wa-iyyakumwahuwa assameeAAu alAAaleem","juz":21,"page":403},{"s":29,"a":61,"key":"29:61","ar":"وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ لَيَقُولُنَّ ٱللَّهُ ۖ فَأَنَّىٰ يُؤْفَكُونَ","en":"If you asked them, \"Who created the heavens and earth and subjected the sun and the moon?\" they would surely say, \"Allāh.\" Then how are they deluded?","tr":"Wala-in saaltahum man khalaqa assamawatiwal-arda wasakhkhara ashshamsa walqamaralayaqoolunna Allahu faanna yu/fakoon","juz":21,"page":403},{"s":29,"a":62,"key":"29:62","ar":"ٱللَّهُ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ لَهُۥٓ ۚ إِنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"Allāh extends provision for whom He wills of His servants and restricts for him. Indeed Allāh is, of all things, Knowing.","tr":"Allahu yabsutu arrizqaliman yashao min AAibadihi wayaqdiru lahu inna Allahabikulli shay-in AAaleem","juz":21,"page":403},{"s":29,"a":63,"key":"29:63","ar":"وَلَئِن سَأَلْتَهُم مَّن نَّزَّلَ مِنَ ٱلسَّمَآءِ مَآءً فَأَحْيَا بِهِ ٱلْأَرْضَ مِنۢ بَعْدِ مَوْتِهَا لَيَقُولُنَّ ٱللَّهُ ۚ قُلِ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْقِلُونَ","en":"And if you asked them, \"Who sends down rain from the sky and gives life thereby to the earth after its lifelessness?\" they would surely say, \"Allāh.\" Say, \"Praise to Allāh\"; but most of them do not reason.","tr":"Wala-in saaltahum man nazzala mina assama-imaan faahya bihi al-arda min baAAdimawtiha layaqoolunna Allahu quli alhamdulillahi bal aktharuhum la yaAAqiloon","juz":21,"page":403},{"s":29,"a":64,"key":"29:64","ar":"وَمَا هَـٰذِهِ ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا لَهْوٌ وَلَعِبٌ ۚ وَإِنَّ ٱلدَّارَ ٱلْـَٔاخِرَةَ لَهِىَ ٱلْحَيَوَانُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ","en":"And this worldly life is not but diversion and amusement. And indeed, the home of the Hereafter - that is the [eternal] life, if only they knew.","tr":"Wama hathihi alhayatuaddunya illa lahwun walaAAibun wa-inna addaraal-akhirata lahiya alhayawanu law kanooyaAAlamoon","juz":21,"page":404},{"s":29,"a":65,"key":"29:65","ar":"فَإِذَا رَكِبُوا۟ فِى ٱلْفُلْكِ دَعَوُا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ فَلَمَّا نَجَّىٰهُمْ إِلَى ٱلْبَرِّ إِذَا هُمْ يُشْرِكُونَ","en":"And when they board a ship, they supplicate Allāh, sincere to Him in religion [i.e., faith and hope]. But when He delivers them to the land, at once they associate others with Him","tr":"Fa-itha rakiboo fee alfulki daAAawooAllaha mukhliseena lahu addeena falammanajjahum ila albarri itha hum yushrikoon","juz":21,"page":404},{"s":29,"a":66,"key":"29:66","ar":"لِيَكْفُرُوا۟ بِمَآ ءَاتَيْنَـٰهُمْ وَلِيَتَمَتَّعُوا۟ ۖ فَسَوْفَ يَعْلَمُونَ","en":"So that they will deny what We have granted them, and they will enjoy themselves. But they are going to know.1","tr":"Liyakfuroo bima ataynahumwaliyatamattaAAoo fasawfa yaAAlamoon","juz":21,"page":404},{"s":29,"a":67,"key":"29:67","ar":"أَوَلَمْ يَرَوْا۟ أَنَّا جَعَلْنَا حَرَمًا ءَامِنًا وَيُتَخَطَّفُ ٱلنَّاسُ مِنْ حَوْلِهِمْ ۚ أَفَبِٱلْبَـٰطِلِ يُؤْمِنُونَ وَبِنِعْمَةِ ٱللَّهِ يَكْفُرُونَ","en":"Have they not seen that We made [Makkah] a safe sanctuary, while people are being taken away1 all around them? Then in falsehood do they believe, and in the favor of Allāh they disbelieve?","tr":"Awa lam yaraw anna jaAAalna haramanaminan wayutakhattafu annasu min hawlihimafabilbatili yu/minoona wabiniAAmati Allahiyakfuroon","juz":21,"page":404},{"s":29,"a":68,"key":"29:68","ar":"وَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَوْ كَذَّبَ بِٱلْحَقِّ لَمَّا جَآءَهُۥٓ ۚ أَلَيْسَ فِى جَهَنَّمَ مَثْوًى لِّلْكَـٰفِرِينَ","en":"And who is more unjust than one who invents a lie about Allāh or denies the truth when it has come to him? Is there not in Hell a [sufficient] residence for the disbelievers?","tr":"Waman athlamu mimmani iftaraAAala Allahi kathiban aw kaththaba bilhaqqilamma jaahu alaysa fee jahannama mathwan lilkafireen","juz":21,"page":404},{"s":29,"a":69,"key":"29:69","ar":"وَٱلَّذِينَ جَـٰهَدُوا۟ فِينَا لَنَهْدِيَنَّهُمْ سُبُلَنَا ۚ وَإِنَّ ٱللَّهَ لَمَعَ ٱلْمُحْسِنِينَ","en":"And those who strive for Us - We will surely guide them to Our ways.1 And indeed, Allāh is with the doers of good.","tr":"Wallatheena jahadoofeena lanahdiyannahum subulana wa-inna AllahalamaAAa almuhsineen","juz":21,"page":404},{"s":30,"a":1,"key":"30:1","ar":" الٓمٓ","en":"Alif, Lām, Meem.1","tr":"Alif-lam-meem","juz":21,"page":404},{"s":30,"a":2,"key":"30:2","ar":"غُلِبَتِ ٱلرُّومُ","en":"The Byzantines have been defeated1","tr":"Ghulibati arroom","juz":21,"page":404},{"s":30,"a":3,"key":"30:3","ar":"فِىٓ أَدْنَى ٱلْأَرْضِ وَهُم مِّنۢ بَعْدِ غَلَبِهِمْ سَيَغْلِبُونَ","en":"In the nearest land.1 But they, after their defeat, will overcome","tr":"Fee adna al-ardi wahum minbaAAdi ghalabihim sayaghliboon","juz":21,"page":404},{"s":30,"a":4,"key":"30:4","ar":"فِى بِضْعِ سِنِينَ ۗ لِلَّهِ ٱلْأَمْرُ مِن قَبْلُ وَمِنۢ بَعْدُ ۚ وَيَوْمَئِذٍ يَفْرَحُ ٱلْمُؤْمِنُونَ","en":"Within three to nine years. To Allāh belongs the command [i.e., decree] before and after. And that day the believers will rejoice","tr":"Fee bidAAi sineena lillahial-amru min qablu wamin baAAdu wayawma-ithin yafrahualmu/minoon","juz":21,"page":404},{"s":30,"a":5,"key":"30:5","ar":"بِنَصْرِ ٱللَّهِ ۚ يَنصُرُ مَن يَشَآءُ ۖ وَهُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"In the victory of Allāh.1 He gives victory to whom He wills, and He is the Exalted in Might, the Merciful.","tr":"Binasri Allahi yansuruman yashao wahuwa alAAazeezu arraheem","juz":21,"page":404},{"s":30,"a":6,"key":"30:6","ar":"وَعْدَ ٱللَّهِ ۖ لَا يُخْلِفُ ٱللَّهُ وَعْدَهُۥ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"[It is] the promise of Allāh. Allāh does not fail in His promise, but most of the people do not know.","tr":"WaAAda Allahi la yukhlifu AllahuwaAAdahu walakinna akthara annasi layaAAlamoon","juz":21,"page":405},{"s":30,"a":7,"key":"30:7","ar":"يَعْلَمُونَ ظَـٰهِرًا مِّنَ ٱلْحَيَوٰةِ ٱلدُّنْيَا وَهُمْ عَنِ ٱلْـَٔاخِرَةِ هُمْ غَـٰفِلُونَ","en":"They know what is apparent of the worldly life, but they, of the Hereafter, are unaware.","tr":"YaAAlamoona thahiranmina alhayati addunya wahum AAanial-akhirati hum ghafiloon","juz":21,"page":405},{"s":30,"a":8,"key":"30:8","ar":"أَوَلَمْ يَتَفَكَّرُوا۟ فِىٓ أَنفُسِهِم ۗ مَّا خَلَقَ ٱللَّهُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَآ إِلَّا بِٱلْحَقِّ وَأَجَلٍ مُّسَمًّى ۗ وَإِنَّ كَثِيرًا مِّنَ ٱلنَّاسِ بِلِقَآئِ رَبِّهِمْ لَكَـٰفِرُونَ","en":"Do they not contemplate within themselves?1 Allāh has not created the heavens and the earth and what is between them except in truth and for a specified term. And indeed, many of the people, in the meeting with their Lord, are disbelievers.","tr":"Awa lam yatafakkaroo fee anfusihim makhalaqa Allahu assamawati wal-ardawama baynahuma illa bilhaqqiwaajalin musamman wa-inna katheeran mina annasibiliqa-i rabbihim lakafiroon","juz":21,"page":405},{"s":30,"a":9,"key":"30:9","ar":"أَوَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَانُوٓا۟ أَشَدَّ مِنْهُمْ قُوَّةً وَأَثَارُوا۟ ٱلْأَرْضَ وَعَمَرُوهَآ أَكْثَرَ مِمَّا عَمَرُوهَا وَجَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَـٰتِ ۖ فَمَا كَانَ ٱللَّهُ لِيَظْلِمَهُمْ وَلَـٰكِن كَانُوٓا۟ أَنفُسَهُمْ يَظْلِمُونَ","en":"Have they not traveled through the earth and observed how was the end of those before them? They were greater than them in power, and they plowed [or excavated] the earth and built it up more than they [i.e., the Makkans] have built it up, and their messengers came to them with clear evidences. And Allāh would not ever have wronged them, but they were wronging themselves.","tr":"Awa lam yaseeroo fee al-ardi fayanthurookayfa kana AAaqibatu allatheena min qablihimkanoo ashadda minhum quwwatan waatharoo al-ardawaAAamarooha akthara mimma AAamarooha wajaat-humrusuluhum bilbayyinati fama kana Allahuliyathlimahum walakin kanoo anfusahumyathlimoon","juz":21,"page":405},{"s":30,"a":10,"key":"30:10","ar":"ثُمَّ كَانَ عَـٰقِبَةَ ٱلَّذِينَ أَسَـٰٓـُٔوا۟ ٱلسُّوٓأَىٰٓ أَن كَذَّبُوا۟ بِـَٔايَـٰتِ ٱللَّهِ وَكَانُوا۟ بِهَا يَسْتَهْزِءُونَ","en":"Then the end of those who did evil was the worst [consequence] because they denied the signs of Allāh and used to ridicule them.","tr":"Thumma kana AAaqibata allatheenaasaoo assoo-a an kaththaboo bi-ayatiAllahi wakanoo biha yastahzi-oon","juz":21,"page":405},{"s":30,"a":11,"key":"30:11","ar":"ٱللَّهُ يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ ثُمَّ إِلَيْهِ تُرْجَعُونَ","en":"Allāh begins creation; then He will repeat it; then to Him you will be returned.","tr":"Allahu yabdao alkhalqa thummayuAAeeduhu thumma ilayhi turjaAAoon","juz":21,"page":405},{"s":30,"a":12,"key":"30:12","ar":"وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يُبْلِسُ ٱلْمُجْرِمُونَ","en":"And the Day the Hour appears the criminals will be in despair.","tr":"Wayawma taqoomu assaAAatuyublisu almujrimoon","juz":21,"page":405},{"s":30,"a":13,"key":"30:13","ar":"وَلَمْ يَكُن لَّهُم مِّن شُرَكَآئِهِمْ شُفَعَـٰٓؤُا۟ وَكَانُوا۟ بِشُرَكَآئِهِمْ كَـٰفِرِينَ","en":"And there will not be for them among their [alleged] partners any intercessors, and they will [then] be disbelievers in their partners.","tr":"Walam yakun lahum min shuraka-ihimshufaAAao wakanoo bishuraka-ihim kafireen","juz":21,"page":405},{"s":30,"a":14,"key":"30:14","ar":"وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يَوْمَئِذٍ يَتَفَرَّقُونَ","en":"And the Day the Hour appears - that Day they will become separated.","tr":"Wayawma taqoomu assaAAatuyawma-ithin yatafarraqoon","juz":21,"page":405},{"s":30,"a":15,"key":"30:15","ar":"فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ فَهُمْ فِى رَوْضَةٍ يُحْبَرُونَ","en":"And as for those who had believed and done righteous deeds, they will be in a garden [of Paradise], delighted.","tr":"Faamma allatheena amanoowaAAamiloo assalihati fahum fee rawdatinyuhbaroon","juz":21,"page":405},{"s":30,"a":16,"key":"30:16","ar":"وَأَمَّا ٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَـٰتِنَا وَلِقَآئِ ٱلْـَٔاخِرَةِ فَأُو۟لَـٰٓئِكَ فِى ٱلْعَذَابِ مُحْضَرُونَ","en":"But as for those who disbelieved and denied Our verses and the meeting of the Hereafter, those will be brought into the punishment [to remain].","tr":"Waamma allatheena kafaroo wakaththaboobi-ayatina waliqa-i al-akhiratifaola-ika fee alAAathabi muhdaroon","juz":21,"page":406},{"s":30,"a":17,"key":"30:17","ar":"فَسُبْحَـٰنَ ٱللَّهِ حِينَ تُمْسُونَ وَحِينَ تُصْبِحُونَ","en":"So exalted is Allāh when you reach the evening and when you reach the morning.","tr":"Fasubhana Allahi heenatumsoona waheena tusbihoon","juz":21,"page":406},{"s":30,"a":18,"key":"30:18","ar":"وَلَهُ ٱلْحَمْدُ فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَعَشِيًّا وَحِينَ تُظْهِرُونَ","en":"And to Him is [due all] praise throughout the heavens and the earth. And [exalted is He] at night and when you are at noon.","tr":"Walahu alhamdu fee assamawatiwal-ardi waAAashiyyan waheena tuthhiroon","juz":21,"page":406},{"s":30,"a":19,"key":"30:19","ar":"يُخْرِجُ ٱلْحَىَّ مِنَ ٱلْمَيِّتِ وَيُخْرِجُ ٱلْمَيِّتَ مِنَ ٱلْحَىِّ وَيُحْىِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا ۚ وَكَذَٰلِكَ تُخْرَجُونَ","en":"He brings the living out of the dead and brings the dead out of the living and brings to life the earth after its lifelessness. And thus will you be brought out.1","tr":"Yukhriju alhayya mina almayyitiwayukhriju almayyita mina alhayyi wayuhyee al-ardabaAAda mawtiha wakathalika tukhrajoon","juz":21,"page":406},{"s":30,"a":20,"key":"30:20","ar":"وَمِنْ ءَايَـٰتِهِۦٓ أَنْ خَلَقَكُم مِّن تُرَابٍ ثُمَّ إِذَآ أَنتُم بَشَرٌ تَنتَشِرُونَ","en":"And of His signs is that He created you from dust; then, suddenly you were human beings dispersing [throughout the earth].","tr":"Wamin ayatihi an khalaqakummin turabin thumma itha antum basharun tantashiroon","juz":21,"page":406},{"s":30,"a":21,"key":"30:21","ar":"وَمِنْ ءَايَـٰتِهِۦٓ أَنْ خَلَقَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَٰجًا لِّتَسْكُنُوٓا۟ إِلَيْهَا وَجَعَلَ بَيْنَكُم مَّوَدَّةً وَرَحْمَةً ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يَتَفَكَّرُونَ","en":"And of His signs is that He created for you from yourselves mates that you may find tranquility in them; and He placed between you affection and mercy. Indeed in that are signs for a people who give thought.","tr":"Wamin ayatihi an khalaqa lakummin anfusikum azwajan litaskunoo ilayha wajaAAalabaynakum mawaddatan warahmatan inna fee thalika laayatinliqawmin yatafakkaroon","juz":21,"page":406},{"s":30,"a":22,"key":"30:22","ar":"وَمِنْ ءَايَـٰتِهِۦ خَلْقُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَٱخْتِلَـٰفُ أَلْسِنَتِكُمْ وَأَلْوَٰنِكُمْ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّلْعَـٰلِمِينَ","en":"And of His signs is the creation of the heavens and the earth and the diversity of your languages and your colors. Indeed in that are signs for those of knowledge.","tr":"Wamin ayatihi khalqu assamawatiwal-ardi wakhtilafu alsinatikumwaalwanikum inna fee thalika laayatinlilAAalimeen","juz":21,"page":406},{"s":30,"a":23,"key":"30:23","ar":"وَمِنْ ءَايَـٰتِهِۦ مَنَامُكُم بِٱلَّيْلِ وَٱلنَّهَارِ وَٱبْتِغَآؤُكُم مِّن فَضْلِهِۦٓ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يَسْمَعُونَ","en":"And of His signs is your sleep by night and day and your seeking of His bounty. Indeed in that are signs for a people who listen.","tr":"Wamin ayatihi manamukumbillayli wannahari wabtighaokummin fadlihi inna fee thalika laayatinliqawmin yasmaAAoon","juz":21,"page":406},{"s":30,"a":24,"key":"30:24","ar":"وَمِنْ ءَايَـٰتِهِۦ يُرِيكُمُ ٱلْبَرْقَ خَوْفًا وَطَمَعًا وَيُنَزِّلُ مِنَ ٱلسَّمَآءِ مَآءً فَيُحْىِۦ بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَآ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يَعْقِلُونَ","en":"And of His signs is [that] He shows you the lightning [causing] fear and aspiration, and He sends down rain from the sky by which He brings to life the earth after its lifelessness. Indeed in that are signs for a people who use reason.","tr":"Wamin ayatihi yureekumualbarqa khawfan watamaAAan wayunazzilu mina assama-imaan fayuhyee bihi al-arda baAAda mawtihainna fee thalika laayatin liqawminyaAAqiloon","juz":21,"page":406},{"s":30,"a":25,"key":"30:25","ar":"وَمِنْ ءَايَـٰتِهِۦٓ أَن تَقُومَ ٱلسَّمَآءُ وَٱلْأَرْضُ بِأَمْرِهِۦ ۚ ثُمَّ إِذَا دَعَاكُمْ دَعْوَةً مِّنَ ٱلْأَرْضِ إِذَآ أَنتُمْ تَخْرُجُونَ","en":"And of His signs is that the heaven and earth stand [i.e., remain] by His command. Then when He calls you with a [single] call from the earth, immediately you will come forth.","tr":"Wamin ayatihi an taqooma assamaowal-ardu bi-amrihi thumma itha daAAakumdaAAwatan mina al-ardi itha antum takhrujoon","juz":21,"page":407},{"s":30,"a":26,"key":"30:26","ar":"وَلَهُۥ مَن فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ كُلٌّ لَّهُۥ قَـٰنِتُونَ","en":"And to Him belongs whoever is in the heavens and earth. All are to Him devoutly obedient.","tr":"Walahu man fee assamawatiwal-ardi kullun lahu qanitoon","juz":21,"page":407},{"s":30,"a":27,"key":"30:27","ar":"وَهُوَ ٱلَّذِى يَبْدَؤُا۟ ٱلْخَلْقَ ثُمَّ يُعِيدُهُۥ وَهُوَ أَهْوَنُ عَلَيْهِ ۚ وَلَهُ ٱلْمَثَلُ ٱلْأَعْلَىٰ فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"And it is He who begins creation; then He repeats it, and that is [even] easier for Him. To Him belongs the highest description [i.e., attribute] in the heavens and earth. And He is the Exalted in Might, the Wise.","tr":"Wahuwa allathee yabdao alkhalqathumma yuAAeeduhu wahuwa ahwanu AAalayhi walahu almathalu al-aAAlafee assamawati wal-ardiwahuwa alAAazeezu alhakeem","juz":21,"page":407},{"s":30,"a":28,"key":"30:28","ar":"ضَرَبَ لَكُم مَّثَلًا مِّنْ أَنفُسِكُمْ ۖ هَل لَّكُم مِّن مَّا مَلَكَتْ أَيْمَـٰنُكُم مِّن شُرَكَآءَ فِى مَا رَزَقْنَـٰكُمْ فَأَنتُمْ فِيهِ سَوَآءٌ تَخَافُونَهُمْ كَخِيفَتِكُمْ أَنفُسَكُمْ ۚ كَذَٰلِكَ نُفَصِّلُ ٱلْـَٔايَـٰتِ لِقَوْمٍ يَعْقِلُونَ","en":"He presents to you an example from yourselves. Do you have among those whom your right hands possess [i.e., slaves] any partners in what We have provided for you so that you are equal therein [and] would fear them as your fear of one another [within a partnership]?1 Thus do We detail the verses for a people who use reason.","tr":"Daraba lakum mathalan min anfusikumhal lakum mimma malakat aymanukum min shurakaafee ma razaqnakum faantum feehi sawaon takhafoonahumkakheefatikum anfusakum kathalika nufassilu al-ayatiliqawmin yaAAqiloon","juz":21,"page":407},{"s":30,"a":29,"key":"30:29","ar":"بَلِ ٱتَّبَعَ ٱلَّذِينَ ظَلَمُوٓا۟ أَهْوَآءَهُم بِغَيْرِ عِلْمٍ ۖ فَمَن يَهْدِى مَنْ أَضَلَّ ٱللَّهُ ۖ وَمَا لَهُم مِّن نَّـٰصِرِينَ","en":"But those who wrong follow their [own] desires without knowledge. Then who can guide one whom Allāh has sent astray? And for them there are no helpers.","tr":"Bali ittabaAAa allatheena thalamooahwaahum bighayri AAilmin faman yahdee man adallaAllahu wama lahum min nasireen","juz":21,"page":407},{"s":30,"a":30,"key":"30:30","ar":"فَأَقِمْ وَجْهَكَ لِلدِّينِ حَنِيفًا ۚ فِطْرَتَ ٱللَّهِ ٱلَّتِى فَطَرَ ٱلنَّاسَ عَلَيْهَا ۚ لَا تَبْدِيلَ لِخَلْقِ ٱللَّهِ ۚ ذَٰلِكَ ٱلدِّينُ ٱلْقَيِّمُ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"So direct your face [i.e., self] toward the religion, inclining to truth. [Adhere to] the fiṭrah1 of Allāh upon which He has created [all] people. No change should there be in the creation of Allāh.2 That is the correct religion, but most of the people do not know.","tr":"Faaqim wajhaka liddeeni haneefanfitrata Allahi allatee fatara annasaAAalayha la tabdeela likhalqi Allahi thalikaaddeenu alqayyimu walakinna akthara annasila yaAAlamoon","juz":21,"page":407},{"s":30,"a":31,"key":"30:31","ar":"۞ مُنِيبِينَ إِلَيْهِ وَٱتَّقُوهُ وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَلَا تَكُونُوا۟ مِنَ ٱلْمُشْرِكِينَ","en":"[Adhere to it], turning in repentance to Him, and fear Him and establish prayer and do not be of those who associate others with Allāh","tr":"Muneebeena ilayhi wattaqoohuwaaqeemoo assalata wala takoonoomina almushrikeen","juz":21,"page":407},{"s":30,"a":32,"key":"30:32","ar":"مِنَ ٱلَّذِينَ فَرَّقُوا۟ دِينَهُمْ وَكَانُوا۟ شِيَعًا ۖ كُلُّ حِزْبٍۭ بِمَا لَدَيْهِمْ فَرِحُونَ","en":"[Or] of those who have divided their religion and become sects, every faction rejoicing in what it has.1","tr":"Mina allatheena farraqoo deenahum wakanooshiyaAAan kullu hizbin bima ladayhim farihoon","juz":21,"page":407},{"s":30,"a":33,"key":"30:33","ar":"وَإِذَا مَسَّ ٱلنَّاسَ ضُرٌّ دَعَوْا۟ رَبَّهُم مُّنِيبِينَ إِلَيْهِ ثُمَّ إِذَآ أَذَاقَهُم مِّنْهُ رَحْمَةً إِذَا فَرِيقٌ مِّنْهُم بِرَبِّهِمْ يُشْرِكُونَ","en":"And when adversity touches the people, they call upon their Lord, turning in repentance to Him. Then when He lets them taste mercy from Him, at once a party of them associate others with their Lord,","tr":"Wa-itha massa annasa durrundaAAaw rabbahum muneebeena ilayhi thumma itha athaqahumminhu rahmatan itha fareequn minhum birabbihimyushrikoon","juz":21,"page":408},{"s":30,"a":34,"key":"30:34","ar":"لِيَكْفُرُوا۟ بِمَآ ءَاتَيْنَـٰهُمْ ۚ فَتَمَتَّعُوا۟ فَسَوْفَ تَعْلَمُونَ","en":"So that they will deny what We have granted them.1 Then enjoy yourselves, for you are going to know.","tr":"Liyakfuroo bima ataynahumfatamattaAAoo fasawfa taAAlamoon","juz":21,"page":408},{"s":30,"a":35,"key":"30:35","ar":"أَمْ أَنزَلْنَا عَلَيْهِمْ سُلْطَـٰنًا فَهُوَ يَتَكَلَّمُ بِمَا كَانُوا۟ بِهِۦ يُشْرِكُونَ","en":"Or have We sent down to them an authority [i.e., a proof or scripture], and it speaks of what they have been associating with Him?","tr":"Am anzalna AAalayhim sultananfahuwa yatakallamu bima kanoo bihi yushrikoon","juz":21,"page":408},{"s":30,"a":36,"key":"30:36","ar":"وَإِذَآ أَذَقْنَا ٱلنَّاسَ رَحْمَةً فَرِحُوا۟ بِهَا ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ إِذَا هُمْ يَقْنَطُونَ","en":"And when We let the people taste mercy, they rejoice therein, but if evil afflicts them for what their hands have put forth, immediately they despair.","tr":"Watha athaqna annasarahmatan farihoo biha wa-in tusibhumsayyi-atun bima qaddamat aydeehim itha hum yaqnatoon","juz":21,"page":408},{"s":30,"a":37,"key":"30:37","ar":"أَوَلَمْ يَرَوْا۟ أَنَّ ٱللَّهَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يُؤْمِنُونَ","en":"Do they not see that Allāh extends provision for whom He wills and restricts [it]? Indeed in that are signs for a people who believe.","tr":"Awa lam yaraw anna Allaha yabsutuarrizqa liman yashao wayaqdiru inna fee thalikalaayatin liqawmin yu/minoon","juz":21,"page":408},{"s":30,"a":38,"key":"30:38","ar":"فَـَٔاتِ ذَا ٱلْقُرْبَىٰ حَقَّهُۥ وَٱلْمِسْكِينَ وَٱبْنَ ٱلسَّبِيلِ ۚ ذَٰلِكَ خَيْرٌ لِّلَّذِينَ يُرِيدُونَ وَجْهَ ٱللَّهِ ۖ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"So give the relative his right, as well as the needy and the traveler. That is best for those who desire the face [i.e., approval] of Allāh, and it is they who will be the successful.","tr":"Faati tha alqurba haqqahuwalmiskeena wabna assabeeli thalikakhayrun lillatheena yureedoona wajha Allahi waola-ikahumu almuflihoon","juz":21,"page":408},{"s":30,"a":39,"key":"30:39","ar":"وَمَآ ءَاتَيْتُم مِّن رِّبًا لِّيَرْبُوَا۟ فِىٓ أَمْوَٰلِ ٱلنَّاسِ فَلَا يَرْبُوا۟ عِندَ ٱللَّهِ ۖ وَمَآ ءَاتَيْتُم مِّن زَكَوٰةٍ تُرِيدُونَ وَجْهَ ٱللَّهِ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُضْعِفُونَ","en":"And whatever you give for interest [i.e., advantage] to increase within the wealth of people1 will not increase with Allāh. But what you give in zakāh,2 desiring the face [i.e., approval] of Allāh - those are the multipliers.3","tr":"Wama ataytum min ribanliyarbuwa fee amwali annasi falayarboo AAinda Allahi wama ataytum min zakatintureedoona wajha Allahi faola-ika humu almudAAifoon","juz":21,"page":408},{"s":30,"a":40,"key":"30:40","ar":"ٱللَّهُ ٱلَّذِى خَلَقَكُمْ ثُمَّ رَزَقَكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يُحْيِيكُمْ ۖ هَلْ مِن شُرَكَآئِكُم مَّن يَفْعَلُ مِن ذَٰلِكُم مِّن شَىْءٍ ۚ سُبْحَـٰنَهُۥ وَتَعَـٰلَىٰ عَمَّا يُشْرِكُونَ","en":"Allāh is the one who created you, then provided for you, then will cause you to die, and then will give you life. Are there any of your \"partners\" who does anything of that? Exalted is He and high above what they associate with Him.","tr":"Allahu allathee khalaqakumthumma razaqakum thumma yumeetukum thumma yuhyeekum halmin shuraka-ikum man yafAAalu min thalikum minshay-in subhanahu wataAAala AAammayushrikoon","juz":21,"page":408},{"s":30,"a":41,"key":"30:41","ar":"ظَهَرَ ٱلْفَسَادُ فِى ٱلْبَرِّ وَٱلْبَحْرِ بِمَا كَسَبَتْ أَيْدِى ٱلنَّاسِ لِيُذِيقَهُم بَعْضَ ٱلَّذِى عَمِلُوا۟ لَعَلَّهُمْ يَرْجِعُونَ","en":"Corruption has appeared throughout the land and sea by [reason of] what the hands of people have earned so He [i.e., Allāh] may let them taste part of [the consequence of] what they have done that perhaps they will return [to righteousness].","tr":"Thahara alfasadu feealbarri walbahri bima kasabat aydee annasiliyutheeqahum baAAda allathee AAamiloolaAAallahum yarjiAAoon","juz":21,"page":408},{"s":30,"a":42,"key":"30:42","ar":"قُلْ سِيرُوا۟ فِى ٱلْأَرْضِ فَٱنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلَّذِينَ مِن قَبْلُ ۚ كَانَ أَكْثَرُهُم مُّشْرِكِينَ","en":"Say, [O Muḥammad], \"Travel through the land and observe how was the end of those before. Most of them were associators [of others with Allāh].","tr":"Qul seeroo fee al-ardi fanthurookayfa kana AAaqibatu allatheena min qablu kanaaktharuhum mushrikeen","juz":21,"page":409},{"s":30,"a":43,"key":"30:43","ar":"فَأَقِمْ وَجْهَكَ لِلدِّينِ ٱلْقَيِّمِ مِن قَبْلِ أَن يَأْتِىَ يَوْمٌ لَّا مَرَدَّ لَهُۥ مِنَ ٱللَّهِ ۖ يَوْمَئِذٍ يَصَّدَّعُونَ","en":"So direct your face [i.e., self] toward the correct religion before a Day comes from Allāh of which there is no repelling. That Day, they will be divided.1","tr":"Faaqim wajhaka liddeeni alqayyimimin qabli an ya/tiya yawmun la maradda lahu mina Allahiyawma-ithin yassaddaAAoon","juz":21,"page":409},{"s":30,"a":44,"key":"30:44","ar":"مَن كَفَرَ فَعَلَيْهِ كُفْرُهُۥ ۖ وَمَنْ عَمِلَ صَـٰلِحًا فَلِأَنفُسِهِمْ يَمْهَدُونَ","en":"Whoever disbelieves - upon him is [the consequence of] his disbelief. And whoever does righteousness - they are for themselves preparing,","tr":"Man kafara faAAalayhi kufruhu waman AAamila salihanfali-anfusihim yamhadoon","juz":21,"page":409},{"s":30,"a":45,"key":"30:45","ar":"لِيَجْزِىَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ مِن فَضْلِهِۦٓ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلْكَـٰفِرِينَ","en":"That He may reward those who have believed and done righteous deeds out of His bounty. Indeed, He does not like the disbelievers.","tr":"Liyajziya allatheena amanoowaAAamiloo assalihati min fadlihiinnahu la yuhibbu alkafireen","juz":21,"page":409},{"s":30,"a":46,"key":"30:46","ar":"وَمِنْ ءَايَـٰتِهِۦٓ أَن يُرْسِلَ ٱلرِّيَاحَ مُبَشِّرَٰتٍ وَلِيُذِيقَكُم مِّن رَّحْمَتِهِۦ وَلِتَجْرِىَ ٱلْفُلْكُ بِأَمْرِهِۦ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ","en":"And of His signs is that He sends the winds as bringers of good tidings and to let you taste His mercy [i.e., rain] and so the ships may sail at His command and so you may seek of His bounty, and perhaps you will be grateful.","tr":"Wamin ayatihi an yursila arriyahamubashshiratin waliyutheeqakum min rahmatihiwalitajriya alfulku bi-amrihi walitabtaghoo min fadlihiwalaAAallakum tashkuroon","juz":21,"page":409},{"s":30,"a":47,"key":"30:47","ar":"وَلَقَدْ أَرْسَلْنَا مِن قَبْلِكَ رُسُلًا إِلَىٰ قَوْمِهِمْ فَجَآءُوهُم بِٱلْبَيِّنَـٰتِ فَٱنتَقَمْنَا مِنَ ٱلَّذِينَ أَجْرَمُوا۟ ۖ وَكَانَ حَقًّا عَلَيْنَا نَصْرُ ٱلْمُؤْمِنِينَ","en":"And We have already sent messengers before you to their peoples, and they came to them with clear evidences; then We took retribution from those who committed crimes, and incumbent upon Us was support1 of the believers.","tr":"Walaqad arsalna min qablika rusulanila qawmihim fajaoohum bilbayyinatifantaqamna mina allatheena ajramoo wakanahaqqan AAalayna nasru almu/mineen","juz":21,"page":409},{"s":30,"a":48,"key":"30:48","ar":"ٱللَّهُ ٱلَّذِى يُرْسِلُ ٱلرِّيَـٰحَ فَتُثِيرُ سَحَابًا فَيَبْسُطُهُۥ فِى ٱلسَّمَآءِ كَيْفَ يَشَآءُ وَيَجْعَلُهُۥ كِسَفًا فَتَرَى ٱلْوَدْقَ يَخْرُجُ مِنْ خِلَـٰلِهِۦ ۖ فَإِذَآ أَصَابَ بِهِۦ مَن يَشَآءُ مِنْ عِبَادِهِۦٓ إِذَا هُمْ يَسْتَبْشِرُونَ","en":"It is Allāh who sends the winds, and they stir the clouds and spread them in the sky however He wills, and He makes them fragments so you see the rain emerge from within them. And when He causes it to fall upon whom He wills of His servants, immediately they rejoice","tr":"Allahu allathee yursilu arriyahafatutheeru sahaban fayabsutuhu fee assama-ikayfa yashao wayajAAaluhu kisafan fatara alwadqayakhruju min khilalihi fa-itha asaba bihiman yashao min AAibadihi itha humyastabshiroon","juz":21,"page":409},{"s":30,"a":49,"key":"30:49","ar":"وَإِن كَانُوا۟ مِن قَبْلِ أَن يُنَزَّلَ عَلَيْهِم مِّن قَبْلِهِۦ لَمُبْلِسِينَ","en":"Although they were, before it was sent down upon them - before that, in despair.","tr":"Wa-in kanoo min qabli an yunazzalaAAalayhim min qablihi lamubliseen","juz":21,"page":409},{"s":30,"a":50,"key":"30:50","ar":"فَٱنظُرْ إِلَىٰٓ ءَاثَـٰرِ رَحْمَتِ ٱللَّهِ كَيْفَ يُحْىِ ٱلْأَرْضَ بَعْدَ مَوْتِهَآ ۚ إِنَّ ذَٰلِكَ لَمُحْىِ ٱلْمَوْتَىٰ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"So observe the effects of the mercy of Allāh - how He gives life to the earth after its lifelessness. Indeed, that [same one] will give life to the dead, and He is over all things competent.","tr":"Fanthur ila atharirahmati Allahi kayfa yuhyee al-ardabaAAda mawtiha inna thalika lamuhyee almawtawahuwa AAala kulli shay-in qadeer","juz":21,"page":409},{"s":30,"a":51,"key":"30:51","ar":"وَلَئِنْ أَرْسَلْنَا رِيحًا فَرَأَوْهُ مُصْفَرًّا لَّظَلُّوا۟ مِنۢ بَعْدِهِۦ يَكْفُرُونَ","en":"But if We should send a [bad] wind and they saw [their crops] turned yellow, they would remain thereafter disbelievers.1","tr":"Wala-in arsalna reehanfaraawhu musfarran lathalloo min baAAdihiyakfuroon","juz":21,"page":410},{"s":30,"a":52,"key":"30:52","ar":"فَإِنَّكَ لَا تُسْمِعُ ٱلْمَوْتَىٰ وَلَا تُسْمِعُ ٱلصُّمَّ ٱلدُّعَآءَ إِذَا وَلَّوْا۟ مُدْبِرِينَ","en":"So indeed, you will not make the dead hear, nor will you make the deaf hear the call when they turn their backs, retreating.","tr":"Fa-innaka la tusmiAAu almawtawala tusmiAAu assumma adduAAaaitha wallaw mudbireen","juz":21,"page":410},{"s":30,"a":53,"key":"30:53","ar":"وَمَآ أَنتَ بِهَـٰدِ ٱلْعُمْىِ عَن ضَلَـٰلَتِهِمْ ۖ إِن تُسْمِعُ إِلَّا مَن يُؤْمِنُ بِـَٔايَـٰتِنَا فَهُم مُّسْلِمُونَ","en":"And you cannot guide the blind away from their error. You will only make hear those who believe in Our verses so they are Muslims [in submission to Allāh].","tr":"Wama anta bihadi alAAumyi AAandalalatihim in tusmiAAu illa man yu/minu bi-ayatinafahum muslimoon","juz":21,"page":410},{"s":30,"a":54,"key":"30:54","ar":"۞ ٱللَّهُ ٱلَّذِى خَلَقَكُم مِّن ضَعْفٍ ثُمَّ جَعَلَ مِنۢ بَعْدِ ضَعْفٍ قُوَّةً ثُمَّ جَعَلَ مِنۢ بَعْدِ قُوَّةٍ ضَعْفًا وَشَيْبَةً ۚ يَخْلُقُ مَا يَشَآءُ ۖ وَهُوَ ٱلْعَلِيمُ ٱلْقَدِيرُ","en":"Allāh is the one who created you from weakness, then made after weakness strength, then made after strength weakness and white hair. He creates what He wills, and He is the Knowing, the Competent.","tr":"Allahu allathee khalaqakum mindaAAfin thumma jaAAala min baAAdi daAAfin quwwatanthumma jaAAala min baAAdi quwwatin daAAfan washaybatanyakhluqu ma yashao wahuwa alAAaleemu alqadeer","juz":21,"page":410},{"s":30,"a":55,"key":"30:55","ar":"وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يُقْسِمُ ٱلْمُجْرِمُونَ مَا لَبِثُوا۟ غَيْرَ سَاعَةٍ ۚ كَذَٰلِكَ كَانُوا۟ يُؤْفَكُونَ","en":"And the Day the Hour appears the criminals will swear they had remained but an hour. Thus they were deluded.","tr":"Wayawma taqoomu assaAAatuyuqsimu almujrimoona ma labithoo ghayra saAAatin kathalikakanoo yu/fakoon","juz":21,"page":410},{"s":30,"a":56,"key":"30:56","ar":"وَقَالَ ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ وَٱلْإِيمَـٰنَ لَقَدْ لَبِثْتُمْ فِى كِتَـٰبِ ٱللَّهِ إِلَىٰ يَوْمِ ٱلْبَعْثِ ۖ فَهَـٰذَا يَوْمُ ٱلْبَعْثِ وَلَـٰكِنَّكُمْ كُنتُمْ لَا تَعْلَمُونَ","en":"But those who were given knowledge and faith will say, \"You remained the extent of Allāh's decree until the Day of Resurrection, and this is the Day of Resurrection, but you did not used to know.\"1","tr":"Waqala allatheena ootooalAAilma wal-eemana laqad labithtum fee kitabiAllahi ila yawmi albaAAthi fahatha yawmualbaAAthi walakinnakum kuntum la taAAlamoon","juz":21,"page":410},{"s":30,"a":57,"key":"30:57","ar":"فَيَوْمَئِذٍ لَّا يَنفَعُ ٱلَّذِينَ ظَلَمُوا۟ مَعْذِرَتُهُمْ وَلَا هُمْ يُسْتَعْتَبُونَ","en":"So that Day, their excuse will not benefit those who wronged, nor will they be asked to appease [Allāh].","tr":"Fayawma-ithin la yanfaAAu allatheenathalamoo maAAthiratuhum wala humyustaAAtaboon","juz":21,"page":410},{"s":30,"a":58,"key":"30:58","ar":"وَلَقَدْ ضَرَبْنَا لِلنَّاسِ فِى هَـٰذَا ٱلْقُرْءَانِ مِن كُلِّ مَثَلٍ ۚ وَلَئِن جِئْتَهُم بِـَٔايَةٍ لَّيَقُولَنَّ ٱلَّذِينَ كَفَرُوٓا۟ إِنْ أَنتُمْ إِلَّا مُبْطِلُونَ","en":"And We have certainly presented to the people in this Qur’ān from every [kind of] example. But, [O Muḥammad], if you should bring them a sign, the disbelievers will surely say, \"You [believers] are but falsifiers.\"","tr":"Walaqad darabna linnasifee hatha alqur-ani min kulli mathalin wala-inji/tahum bi-ayatin layaqoolanna allatheena kafarooin antum illa mubtiloon","juz":21,"page":410},{"s":30,"a":59,"key":"30:59","ar":"كَذَٰلِكَ يَطْبَعُ ٱللَّهُ عَلَىٰ قُلُوبِ ٱلَّذِينَ لَا يَعْلَمُونَ","en":"Thus does Allāh seal the hearts of those who do not know.1","tr":"Kathalika yatbaAAu AllahuAAala quloobi allatheena la yaAAlamoon","juz":21,"page":410},{"s":30,"a":60,"key":"30:60","ar":"فَٱصْبِرْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ ۖ وَلَا يَسْتَخِفَّنَّكَ ٱلَّذِينَ لَا يُوقِنُونَ","en":"So be patient. Indeed, the promise of Allāh is truth. And let them not disquiet you who are not certain [in faith].","tr":"Fasbir inna waAAda Allahihaqqun wala yastakhiffannaka allatheena layooqinoon","juz":21,"page":410},{"s":31,"a":1,"key":"31:1","ar":" الٓمٓ","en":"Alif, Lām, Meem.1","tr":"Alif-lam-meem","juz":21,"page":411},{"s":31,"a":2,"key":"31:2","ar":"تِلْكَ ءَايَـٰتُ ٱلْكِتَـٰبِ ٱلْحَكِيمِ","en":"These are verses of the wise1 Book,","tr":"Tilka ayatu alkitabi alhakeem","juz":21,"page":411},{"s":31,"a":3,"key":"31:3","ar":"هُدًى وَرَحْمَةً لِّلْمُحْسِنِينَ","en":"As guidance and mercy for the doers of good","tr":"Hudan warahmatan lilmuhsineen","juz":21,"page":411},{"s":31,"a":4,"key":"31:4","ar":"ٱلَّذِينَ يُقِيمُونَ ٱلصَّلَوٰةَ وَيُؤْتُونَ ٱلزَّكَوٰةَ وَهُم بِٱلْـَٔاخِرَةِ هُمْ يُوقِنُونَ","en":"Who establish prayer and give zakāh, and they, of the Hereafter, are certain [in faith].","tr":"Allatheena yuqeemoona assalatawayu/toona azzakata wahum bil-akhiratihum yooqinoon","juz":21,"page":411},{"s":31,"a":5,"key":"31:5","ar":"أُو۟لَـٰٓئِكَ عَلَىٰ هُدًى مِّن رَّبِّهِمْ ۖ وَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"Those are on [right] guidance from their Lord, and it is those who are the successful.","tr":"Ola-ika AAala hudan minrabbihim waola-ika humu almuflihoon","juz":21,"page":411},{"s":31,"a":6,"key":"31:6","ar":"وَمِنَ ٱلنَّاسِ مَن يَشْتَرِى لَهْوَ ٱلْحَدِيثِ لِيُضِلَّ عَن سَبِيلِ ٱللَّهِ بِغَيْرِ عِلْمٍ وَيَتَّخِذَهَا هُزُوًا ۚ أُو۟لَـٰٓئِكَ لَهُمْ عَذَابٌ مُّهِينٌ","en":"And of the people is he who buys the amusement of speech1 to mislead [others] from the way of Allāh without knowledge and who takes it [i.e., His way] in ridicule. Those will have a humiliating punishment.","tr":"Wamina annasi man yashtareelahwa alhadeethi liyudilla AAan sabeeli Allahibighayri AAilmin wayattakhithaha huzuwan ola-ikalahum AAathabun muheen","juz":21,"page":411},{"s":31,"a":7,"key":"31:7","ar":"وَإِذَا تُتْلَىٰ عَلَيْهِ ءَايَـٰتُنَا وَلَّىٰ مُسْتَكْبِرًا كَأَن لَّمْ يَسْمَعْهَا كَأَنَّ فِىٓ أُذُنَيْهِ وَقْرًا ۖ فَبَشِّرْهُ بِعَذَابٍ أَلِيمٍ","en":"And when Our verses are recited to him, he turns away arrogantly as if he had not heard them, as if there was in his ears deafness. So give him tidings of a painful punishment.","tr":"Wa-itha tutla AAalayhi ayatunawalla mustakbiran kaan lam yasmaAAha kaanna fee othunayhiwaqran fabashshirhu biAAathabin aleem","juz":21,"page":411},{"s":31,"a":8,"key":"31:8","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَهُمْ جَنَّـٰتُ ٱلنَّعِيمِ","en":"Indeed, those who believe and do righteous deeds - for them are the Gardens of Pleasure,","tr":"Inna allatheena amanoowaAAamiloo assalihati lahum jannatuannaAAeem","juz":21,"page":411},{"s":31,"a":9,"key":"31:9","ar":"خَـٰلِدِينَ فِيهَا ۖ وَعْدَ ٱللَّهِ حَقًّا ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Wherein they abide eternally; [it is] the promise of Allāh [which is] truth. And He is the Exalted in Might, the Wise.","tr":"Khalideena feeha waAAda Allahihaqqan wahuwa alAAazeezu alhakeem","juz":21,"page":411},{"s":31,"a":10,"key":"31:10","ar":"خَلَقَ ٱلسَّمَـٰوَٰتِ بِغَيْرِ عَمَدٍ تَرَوْنَهَا ۖ وَأَلْقَىٰ فِى ٱلْأَرْضِ رَوَٰسِىَ أَن تَمِيدَ بِكُمْ وَبَثَّ فِيهَا مِن كُلِّ دَآبَّةٍ ۚ وَأَنزَلْنَا مِنَ ٱلسَّمَآءِ مَآءً فَأَنۢبَتْنَا فِيهَا مِن كُلِّ زَوْجٍ كَرِيمٍ","en":"He created the heavens without pillars that you see and has cast into the earth firmly set mountains, lest it should shift with you, and dispersed therein from every creature. And We sent down rain from the sky and made grow therein [plants] of every noble kind.","tr":"Khalaqa assamawatibighayri AAamadin tarawnaha waalqa fee al-ardirawasiya an tameeda bikum wabaththa feeha min kullidabbatin waanzalna mina assama-i maanfaanbatna feeha min kulli zawjin kareem","juz":21,"page":411},{"s":31,"a":11,"key":"31:11","ar":"هَـٰذَا خَلْقُ ٱللَّهِ فَأَرُونِى مَاذَا خَلَقَ ٱلَّذِينَ مِن دُونِهِۦ ۚ بَلِ ٱلظَّـٰلِمُونَ فِى ضَلَـٰلٍ مُّبِينٍ","en":"This is the creation of Allāh. So show Me what those other than Him have created. Rather, the wrongdoers are in clear error.","tr":"Hatha khalqu Allahi faarooneematha khalaqa allatheena min doonihi bali aththalimoonafee dalalin mubeen","juz":21,"page":411},{"s":31,"a":12,"key":"31:12","ar":"وَلَقَدْ ءَاتَيْنَا لُقْمَـٰنَ ٱلْحِكْمَةَ أَنِ ٱشْكُرْ لِلَّهِ ۚ وَمَن يَشْكُرْ فَإِنَّمَا يَشْكُرُ لِنَفْسِهِۦ ۖ وَمَن كَفَرَ فَإِنَّ ٱللَّهَ غَنِىٌّ حَمِيدٌ","en":"And We had certainly given Luqmān wisdom [and said], \"Be grateful to Allāh.\" And whoever is grateful is grateful for [the benefit of] himself. And whoever denies [His favor] - then indeed, Allāh is Free of need and Praiseworthy.","tr":"Walaqad atayna luqmanaalhikmata ani oshkur lillahi waman yashkur fa-innamayashkuru linafsihi waman kafara fa-inna Allaha ghaniyyun hameed","juz":21,"page":412},{"s":31,"a":13,"key":"31:13","ar":"وَإِذْ قَالَ لُقْمَـٰنُ لِٱبْنِهِۦ وَهُوَ يَعِظُهُۥ يَـٰبُنَىَّ لَا تُشْرِكْ بِٱللَّهِ ۖ إِنَّ ٱلشِّرْكَ لَظُلْمٌ عَظِيمٌ","en":"And [mention, O Muḥammad], when Luqmān said to his son while he was instructing him, \"O my son, do not associate [anything] with Allāh. Indeed, association [with Him] is great injustice.\"","tr":"Wa-ith qala luqmanu libnihiwahuwa yaAAithuhu ya bunayya latushrik billahi inna ashshirka lathulmunAAatheem","juz":21,"page":412},{"s":31,"a":14,"key":"31:14","ar":"وَوَصَّيْنَا ٱلْإِنسَـٰنَ بِوَٰلِدَيْهِ حَمَلَتْهُ أُمُّهُۥ وَهْنًا عَلَىٰ وَهْنٍ وَفِصَـٰلُهُۥ فِى عَامَيْنِ أَنِ ٱشْكُرْ لِى وَلِوَٰلِدَيْكَ إِلَىَّ ٱلْمَصِيرُ","en":"And We have enjoined upon man [care] for his parents. His mother carried him, [increasing her] in weakness upon weakness, and his weaning is in two years. Be grateful to Me and to your parents; to Me is the [final] destination.","tr":"Wawassayna al-insanabiwalidayhi hamalat-hu ommuhu wahnan AAalawahnin wafisaluhu fee AAamayni ani oshkur lee waliwalidaykailayya almaseer","juz":21,"page":412},{"s":31,"a":15,"key":"31:15","ar":"وَإِن جَـٰهَدَاكَ عَلَىٰٓ أَن تُشْرِكَ بِى مَا لَيْسَ لَكَ بِهِۦ عِلْمٌ فَلَا تُطِعْهُمَا ۖ وَصَاحِبْهُمَا فِى ٱلدُّنْيَا مَعْرُوفًا ۖ وَٱتَّبِعْ سَبِيلَ مَنْ أَنَابَ إِلَىَّ ۚ ثُمَّ إِلَىَّ مَرْجِعُكُمْ فَأُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ","en":"But if they endeavor to make you associate with Me that of which you have no knowledge,1 do not obey them but accompany them in [this] world with appropriate kindness and follow the way of those who turn back to Me [in repentance]. Then to Me will be your return, and I will inform you about what you used to do.","tr":"Wa-in jahadaka AAala antushrika bee ma laysa laka bihi AAilmun fala tutiAAhumawasahibhuma fee addunya maAAroofanwattabiAA sabeela man anaba ilayya thumma ilayyamarjiAAukum faonabbi-okum bima kuntum taAAmaloon","juz":21,"page":412},{"s":31,"a":16,"key":"31:16","ar":"يَـٰبُنَىَّ إِنَّهَآ إِن تَكُ مِثْقَالَ حَبَّةٍ مِّنْ خَرْدَلٍ فَتَكُن فِى صَخْرَةٍ أَوْ فِى ٱلسَّمَـٰوَٰتِ أَوْ فِى ٱلْأَرْضِ يَأْتِ بِهَا ٱللَّهُ ۚ إِنَّ ٱللَّهَ لَطِيفٌ خَبِيرٌ","en":"[And Luqmān said], \"O my son, indeed if it [i.e., a wrong] should be the weight of a mustard seed and should be within a rock or [anywhere] in the heavens or in the earth, Allāh will bring it forth. Indeed, Allāh is Subtle1 and Aware.","tr":"Ya bunayya innaha in takumithqala habbatin min khardalin fatakun fee sakhratinaw fee assamawati aw fee al-ardiya/ti biha Allahu inna Allaha lateefunkhabeer","juz":21,"page":412},{"s":31,"a":17,"key":"31:17","ar":"يَـٰبُنَىَّ أَقِمِ ٱلصَّلَوٰةَ وَأْمُرْ بِٱلْمَعْرُوفِ وَٱنْهَ عَنِ ٱلْمُنكَرِ وَٱصْبِرْ عَلَىٰ مَآ أَصَابَكَ ۖ إِنَّ ذَٰلِكَ مِنْ عَزْمِ ٱلْأُمُورِ","en":"O my son, establish prayer, enjoin what is right, forbid what is wrong, and be patient over what befalls you. Indeed, [all] that is of the matters [requiring] resolve.1","tr":"Ya bunayya aqimi assalatawa/mur bilmaAAroofi wanha AAani almunkari wasbirAAala ma asabaka inna thalika minAAazmi al-omoor","juz":21,"page":412},{"s":31,"a":18,"key":"31:18","ar":"وَلَا تُصَعِّرْ خَدَّكَ لِلنَّاسِ وَلَا تَمْشِ فِى ٱلْأَرْضِ مَرَحًا ۖ إِنَّ ٱللَّهَ لَا يُحِبُّ كُلَّ مُخْتَالٍ فَخُورٍ","en":"And do not turn your cheek [in contempt] toward people1 and do not walk through the earth exultantly. Indeed, Allāh does not like everyone self-deluded and boastful.","tr":"Wala tusaAAAAir khaddaka linnasiwala tamshi fee al-ardi marahan inna Allahala yuhibbu kulla mukhtalin fakhoor","juz":21,"page":412},{"s":31,"a":19,"key":"31:19","ar":"وَٱقْصِدْ فِى مَشْيِكَ وَٱغْضُضْ مِن صَوْتِكَ ۚ إِنَّ أَنكَرَ ٱلْأَصْوَٰتِ لَصَوْتُ ٱلْحَمِيرِ","en":"And be moderate in your pace and lower your voice; indeed, the most disagreeable of sounds is the voice of donkeys.\"","tr":"Waqsid fee mashyika waghdudmin sawtika inna ankara al-aswati lasawtualhameer","juz":21,"page":412},{"s":31,"a":20,"key":"31:20","ar":"أَلَمْ تَرَوْا۟ أَنَّ ٱللَّهَ سَخَّرَ لَكُم مَّا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ وَأَسْبَغَ عَلَيْكُمْ نِعَمَهُۥ ظَـٰهِرَةً وَبَاطِنَةً ۗ وَمِنَ ٱلنَّاسِ مَن يُجَـٰدِلُ فِى ٱللَّهِ بِغَيْرِ عِلْمٍ وَلَا هُدًى وَلَا كِتَـٰبٍ مُّنِيرٍ","en":"Do you not see that Allāh has made subject to you whatever is in the heavens and whatever is in the earth and amply bestowed upon you His favors, [both] apparent and unapparent? But of the people is he who disputes about Allāh without knowledge or guidance or an enlightening Book [from Him].","tr":"Alam taraw anna Allaha sakhkharalakum ma fee assamawati wamafee al-ardi waasbagha AAalaykum niAAamahu thahiratanwabatinatan wamina annasi man yujadilufee Allahi bighayri AAilmin wala hudan walakitabin muneer","juz":21,"page":413},{"s":31,"a":21,"key":"31:21","ar":"وَإِذَا قِيلَ لَهُمُ ٱتَّبِعُوا۟ مَآ أَنزَلَ ٱللَّهُ قَالُوا۟ بَلْ نَتَّبِعُ مَا وَجَدْنَا عَلَيْهِ ءَابَآءَنَآ ۚ أَوَلَوْ كَانَ ٱلشَّيْطَـٰنُ يَدْعُوهُمْ إِلَىٰ عَذَابِ ٱلسَّعِيرِ","en":"And when it is said to them, \"Follow what Allāh has revealed,\" they say, \"Rather, we will follow that upon which we found our fathers.\" Even if Satan was inviting them to the punishment of the Blaze?","tr":"Wa-itha qeela lahumu ittabiAAoo maanzala Allahu qaloo bal nattabiAAu ma wajadnaAAalayhi abaana awa law kana ashshaytanuyadAAoohum ila AAathabi assaAAeer","juz":21,"page":413},{"s":31,"a":22,"key":"31:22","ar":"۞ وَمَن يُسْلِمْ وَجْهَهُۥٓ إِلَى ٱللَّهِ وَهُوَ مُحْسِنٌ فَقَدِ ٱسْتَمْسَكَ بِٱلْعُرْوَةِ ٱلْوُثْقَىٰ ۗ وَإِلَى ٱللَّهِ عَـٰقِبَةُ ٱلْأُمُورِ","en":"And whoever submits his face [i.e., self] to Allāh while he is a doer of good - then he has grasped the most trustworthy handhold. And to Allāh will be the outcome of [all] matters.","tr":"Waman yuslim wajhahu ila Allahiwahuwa muhsinun faqadi istamsaka bilAAurwatialwuthqa wa-ila Allahi AAaqibatual-omoor","juz":21,"page":413},{"s":31,"a":23,"key":"31:23","ar":"وَمَن كَفَرَ فَلَا يَحْزُنكَ كُفْرُهُۥٓ ۚ إِلَيْنَا مَرْجِعُهُمْ فَنُنَبِّئُهُم بِمَا عَمِلُوٓا۟ ۚ إِنَّ ٱللَّهَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"And whoever has disbelieved - let not his disbelief grieve you. To Us is their return, and We will inform them of what they did. Indeed, Allāh is Knowing of that within the breasts.","tr":"Waman kafara fala yahzunkakufruhu ilayna marjiAAuhum fanunabbi-ohum bimaAAamiloo inna Allaha AAaleemun bithati assudoor","juz":21,"page":413},{"s":31,"a":24,"key":"31:24","ar":"نُمَتِّعُهُمْ قَلِيلًا ثُمَّ نَضْطَرُّهُمْ إِلَىٰ عَذَابٍ غَلِيظٍ","en":"We grant them enjoyment for a little; then We will force them to a massive punishment.","tr":"NumattiAAuhum qaleelan thumma nadtarruhumila AAathabin ghaleeth","juz":21,"page":413},{"s":31,"a":25,"key":"31:25","ar":"وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ لَيَقُولُنَّ ٱللَّهُ ۚ قُلِ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ","en":"And if you asked them, \"Who created the heavens and earth?\" they would surely say, \"Allāh.\" Say, \"[All] praise is [due] to Allāh\"; but most of them do not know.","tr":"Wala-in saaltahum man khalaqa assamawatiwal-arda layaqoolunna Allahu quli alhamdulillahi bal aktharuhum la yaAAlamoon","juz":21,"page":413},{"s":31,"a":26,"key":"31:26","ar":"لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ إِنَّ ٱللَّهَ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ","en":"To Allāh belongs whatever is in the heavens and earth. Indeed, Allāh is the Free of need, the Praiseworthy.","tr":"Lillahi ma fee assamawatiwal-ardi inna Allaha huwa alghaniyyu alhameed","juz":21,"page":413},{"s":31,"a":27,"key":"31:27","ar":"وَلَوْ أَنَّمَا فِى ٱلْأَرْضِ مِن شَجَرَةٍ أَقْلَـٰمٌ وَٱلْبَحْرُ يَمُدُّهُۥ مِنۢ بَعْدِهِۦ سَبْعَةُ أَبْحُرٍ مَّا نَفِدَتْ كَلِمَـٰتُ ٱللَّهِ ۗ إِنَّ ٱللَّهَ عَزِيزٌ حَكِيمٌ","en":"And if whatever trees upon the earth were pens and the sea [was ink], replenished thereafter by seven [more] seas, the words1 of Allāh would not be exhausted. Indeed, Allāh is Exalted in Might and Wise.","tr":"Walaw annama fee al-ardi minshajaratin aqlamun walbahru yamudduhu minbaAAdihi sabAAatu abhurin ma nafidat kalimatuAllahi inna Allaha AAazeezun hakeem","juz":21,"page":413},{"s":31,"a":28,"key":"31:28","ar":"مَّا خَلْقُكُمْ وَلَا بَعْثُكُمْ إِلَّا كَنَفْسٍ وَٰحِدَةٍ ۗ إِنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌ","en":"Your creation and your resurrection will not be but as that of a single soul.1 Indeed, Allāh is Hearing and Seeing.","tr":"Ma khalqukum wala baAAthukumilla kanafsin wahidatin inna AllahasameeAAun baseer","juz":21,"page":413},{"s":31,"a":29,"key":"31:29","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ كُلٌّ يَجْرِىٓ إِلَىٰٓ أَجَلٍ مُّسَمًّى وَأَنَّ ٱللَّهَ بِمَا تَعْمَلُونَ خَبِيرٌ","en":"Do you not see [i.e., know] that Allāh causes the night to enter the day and causes the day to enter the night and has subjected the sun and the moon, each running [its course] for a specified term, and that Allāh, of whatever you do, is Aware?","tr":"Alam tara anna Allaha yooliju allaylafee annahari wayooliju annahara feeallayli wasakhkhara ashshamsa walqamara kullunyajree ila ajalin musamman waanna Allaha bimataAAmaloona khabeer","juz":21,"page":414},{"s":31,"a":30,"key":"31:30","ar":"ذَٰلِكَ بِأَنَّ ٱللَّهَ هُوَ ٱلْحَقُّ وَأَنَّ مَا يَدْعُونَ مِن دُونِهِ ٱلْبَـٰطِلُ وَأَنَّ ٱللَّهَ هُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ","en":"That is because Allāh is the True Reality, and that what they call upon1 other than Him is falsehood, and because Allāh is the Most High, the Grand.","tr":"Thalika bi-anna Allaha huwa alhaqquwaanna ma yadAAoona min doonihi albatilu waanna Allahahuwa alAAaliyyu alkabeer","juz":21,"page":414},{"s":31,"a":31,"key":"31:31","ar":"أَلَمْ تَرَ أَنَّ ٱلْفُلْكَ تَجْرِى فِى ٱلْبَحْرِ بِنِعْمَتِ ٱللَّهِ لِيُرِيَكُم مِّنْ ءَايَـٰتِهِۦٓ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّكُلِّ صَبَّارٍ شَكُورٍ","en":"Do you not see that ships sail through the sea by the favor of Allāh that He may show you of His signs? Indeed in that are signs for everyone patient and grateful.","tr":"Alam tara anna alfulka tajree fee albahribiniAAmati Allahi liyuriyakum min ayatihiinna fee thalika laayatin likulli sabbarinshakoor","juz":21,"page":414},{"s":31,"a":32,"key":"31:32","ar":"وَإِذَا غَشِيَهُم مَّوْجٌ كَٱلظُّلَلِ دَعَوُا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ فَلَمَّا نَجَّىٰهُمْ إِلَى ٱلْبَرِّ فَمِنْهُم مُّقْتَصِدٌ ۚ وَمَا يَجْحَدُ بِـَٔايَـٰتِنَآ إِلَّا كُلُّ خَتَّارٍ كَفُورٍ","en":"And when waves come over them like canopies, they supplicate Allāh, sincere to Him in religion [i.e., faith]. But when He delivers them to the land, there are [some] of them who are moderate [in faith]. And none rejects Our signs except everyone treacherous and ungrateful.","tr":"Wa-itha ghashiyahum mawjun kaththulalidaAAawoo Allaha mukhliseena lahu addeenafalamma najjahum ila albarri faminhum muqtasidunwama yajhadu bi-ayatina illakullu khattarin kafoor","juz":21,"page":414},{"s":31,"a":33,"key":"31:33","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ ٱتَّقُوا۟ رَبَّكُمْ وَٱخْشَوْا۟ يَوْمًا لَّا يَجْزِى وَالِدٌ عَن وَلَدِهِۦ وَلَا مَوْلُودٌ هُوَ جَازٍ عَن وَالِدِهِۦ شَيْـًٔا ۚ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ ۖ فَلَا تَغُرَّنَّكُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا وَلَا يَغُرَّنَّكُم بِٱللَّهِ ٱلْغَرُورُ","en":"O mankind, fear your Lord and fear a Day when no father will avail his son, nor will a son avail his father at all. Indeed, the promise of Allāh is truth, so let not the worldly life delude you and be not deceived about Allāh by the Deceiver [i.e., Satan].","tr":"Ya ayyuha annasuittaqoo rabbakum wakhshaw yawman la yajzee walidunAAan waladihi wala mawloodun huwa jazin AAan walidihishay-an inna waAAda Allahi haqqun falataghurrannakumu alhayatu addunya walayaghurrannakum billahi algharoor","juz":21,"page":414},{"s":31,"a":34,"key":"31:34","ar":"إِنَّ ٱللَّهَ عِندَهُۥ عِلْمُ ٱلسَّاعَةِ وَيُنَزِّلُ ٱلْغَيْثَ وَيَعْلَمُ مَا فِى ٱلْأَرْحَامِ ۖ وَمَا تَدْرِى نَفْسٌ مَّاذَا تَكْسِبُ غَدًا ۖ وَمَا تَدْرِى نَفْسٌۢ بِأَىِّ أَرْضٍ تَمُوتُ ۚ إِنَّ ٱللَّهَ عَلِيمٌ خَبِيرٌۢ","en":"Indeed, Allāh [alone] has knowledge of the Hour and sends down the rain and knows what is in the wombs.1 And no soul perceives what it will earn tomorrow, and no soul perceives in what land it will die. Indeed, Allāh is Knowing and Aware.","tr":"Inna Allaha AAindahu AAilmu assaAAatiwayunazzilu alghaytha wayaAAlamu ma fee al-arhamiwama tadree nafsun matha taksibu ghadan wamatadree nafsun bi-ayyi ardin tamootu inna AllahaAAaleemun khabeer","juz":21,"page":414},{"s":32,"a":1,"key":"32:1","ar":" الٓمٓ","en":"Alif, Lām, Meem.1","tr":"Alif-lam-meem","juz":21,"page":415},{"s":32,"a":2,"key":"32:2","ar":"تَنزِيلُ ٱلْكِتَـٰبِ لَا رَيْبَ فِيهِ مِن رَّبِّ ٱلْعَـٰلَمِينَ","en":"[This is] the revelation of the Book about which there is no doubt from the Lord of the worlds.","tr":"Tanzeelu alkitabi la raybafeehi min rabbi alAAalameen","juz":21,"page":415},{"s":32,"a":3,"key":"32:3","ar":"أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۚ بَلْ هُوَ ٱلْحَقُّ مِن رَّبِّكَ لِتُنذِرَ قَوْمًا مَّآ أَتَىٰهُم مِّن نَّذِيرٍ مِّن قَبْلِكَ لَعَلَّهُمْ يَهْتَدُونَ","en":"Or do they say, \"He invented it\"? Rather, it is the truth from your Lord, [O Muḥammad], that you may warn a people to whom no warner has come before you [so] perhaps they will be guided.","tr":"Am yaqooloona iftarahu bal huwa alhaqqumin rabbika litunthira qawman ma atahum minnatheerin min qablika laAAallahum yahtadoon","juz":21,"page":415},{"s":32,"a":4,"key":"32:4","ar":"ٱللَّهُ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۖ مَا لَكُم مِّن دُونِهِۦ مِن وَلِىٍّ وَلَا شَفِيعٍ ۚ أَفَلَا تَتَذَكَّرُونَ","en":"It is Allāh who created the heavens and the earth and whatever is between them in six days; then He established Himself above the Throne.1 You have not besides Him any protector or any intercessor; so will you not be reminded?","tr":"Allahu allathee khalaqa assamawatiwal-arda wama baynahuma fee sittatiayyamin thumma istawa AAala alAAarshi malakum min doonihi min waliyyin wala shafeeAAin afalatatathakkaroon","juz":21,"page":415},{"s":32,"a":5,"key":"32:5","ar":"يُدَبِّرُ ٱلْأَمْرَ مِنَ ٱلسَّمَآءِ إِلَى ٱلْأَرْضِ ثُمَّ يَعْرُجُ إِلَيْهِ فِى يَوْمٍ كَانَ مِقْدَارُهُۥٓ أَلْفَ سَنَةٍ مِّمَّا تَعُدُّونَ","en":"He arranges [each] matter from the heaven to the earth; then it will ascend to Him in a Day, the extent of which is a thousand years of those which you count.","tr":"Yudabbiru al-amra mina assama-iila al-ardi thumma yaAAruju ilayhi fee yawmin kanamiqdaruhu alfa sanatin mimma taAAuddoon","juz":21,"page":415},{"s":32,"a":6,"key":"32:6","ar":"ذَٰلِكَ عَـٰلِمُ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"That is the Knower of the unseen and the witnessed, the Exalted in Might, the Merciful,","tr":"Thalika AAalimu alghaybi washshahadatialAAazeezu arraheem","juz":21,"page":415},{"s":32,"a":7,"key":"32:7","ar":"ٱلَّذِىٓ أَحْسَنَ كُلَّ شَىْءٍ خَلَقَهُۥ ۖ وَبَدَأَ خَلْقَ ٱلْإِنسَـٰنِ مِن طِينٍ","en":"Who perfected everything which He created and began the creation of man from clay.","tr":"Allathee ahsana kulla shay-inkhalaqahu wabadaa khalqa al-insani min teen","juz":21,"page":415},{"s":32,"a":8,"key":"32:8","ar":"ثُمَّ جَعَلَ نَسْلَهُۥ مِن سُلَـٰلَةٍ مِّن مَّآءٍ مَّهِينٍ","en":"Then He made his posterity out of the extract of a liquid disdained.","tr":"Thumma jaAAala naslahu min sulalatinmin ma-in maheen","juz":21,"page":415},{"s":32,"a":9,"key":"32:9","ar":"ثُمَّ سَوَّىٰهُ وَنَفَخَ فِيهِ مِن رُّوحِهِۦ ۖ وَجَعَلَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَـٰرَ وَٱلْأَفْـِٔدَةَ ۚ قَلِيلًا مَّا تَشْكُرُونَ","en":"Then He proportioned him and breathed into him from His [created] soul1 and made for you hearing and vision and hearts [i.e., intellect]; little are you grateful.","tr":"Thumma sawwahu wanafakha feehi min roohihiwajaAAala lakumu assamAAa wal-absara wal-af-idataqaleelan ma tashkuroon","juz":21,"page":415},{"s":32,"a":10,"key":"32:10","ar":"وَقَالُوٓا۟ أَءِذَا ضَلَلْنَا فِى ٱلْأَرْضِ أَءِنَّا لَفِى خَلْقٍ جَدِيدٍۭ ۚ بَلْ هُم بِلِقَآءِ رَبِّهِمْ كَـٰفِرُونَ","en":"And they say, \"When we are lost [i.e., disintegrated] within the earth, will we indeed be [recreated] in a new creation?\" Rather, they are, in the meeting with their Lord, disbelievers.","tr":"Waqaloo a-itha dalalnafee al-ardi a-inna lafee khalqin jadeedin bal humbiliqa-i rabbihim kafiroon","juz":21,"page":415},{"s":32,"a":11,"key":"32:11","ar":"۞ قُلْ يَتَوَفَّىٰكُم مَّلَكُ ٱلْمَوْتِ ٱلَّذِى وُكِّلَ بِكُمْ ثُمَّ إِلَىٰ رَبِّكُمْ تُرْجَعُونَ","en":"Say, \"The angel of death who has been entrusted with you will take you. Then to your Lord you will be returned.\"","tr":"Qul yatawaffakum malaku almawti allatheewukkila bikum thumma ila rabbikum turjaAAoon","juz":21,"page":415},{"s":32,"a":12,"key":"32:12","ar":"وَلَوْ تَرَىٰٓ إِذِ ٱلْمُجْرِمُونَ نَاكِسُوا۟ رُءُوسِهِمْ عِندَ رَبِّهِمْ رَبَّنَآ أَبْصَرْنَا وَسَمِعْنَا فَٱرْجِعْنَا نَعْمَلْ صَـٰلِحًا إِنَّا مُوقِنُونَ","en":"If you could but see when the criminals are hanging their heads before their Lord, [saying], \"Our Lord, we have seen and heard, so return us [to the world]; we will work righteousness. Indeed, we are [now] certain.\"","tr":"Walaw tara ithi almujrimoona nakisooruoosihim AAinda rabbihim rabbana absarnawasamiAAna faarjiAAna naAAmal salihaninna mooqinoon","juz":21,"page":416},{"s":32,"a":13,"key":"32:13","ar":"وَلَوْ شِئْنَا لَـَٔاتَيْنَا كُلَّ نَفْسٍ هُدَىٰهَا وَلَـٰكِنْ حَقَّ ٱلْقَوْلُ مِنِّى لَأَمْلَأَنَّ جَهَنَّمَ مِنَ ٱلْجِنَّةِ وَٱلنَّاسِ أَجْمَعِينَ","en":"And if We had willed, We could have given every soul its guidance, but the word1 from Me will come into effect [that] \"I will surely fill Hell with jinn and people all together.","tr":"Walaw shi-na laataynakulla nafsin hudaha walakin haqqaalqawlu minnee laamlaanna jahannama mina aljinnati wannasiajmaAAeen","juz":21,"page":416},{"s":32,"a":14,"key":"32:14","ar":"فَذُوقُوا۟ بِمَا نَسِيتُمْ لِقَآءَ يَوْمِكُمْ هَـٰذَآ إِنَّا نَسِينَـٰكُمْ ۖ وَذُوقُوا۟ عَذَابَ ٱلْخُلْدِ بِمَا كُنتُمْ تَعْمَلُونَ","en":"So taste [punishment] because you forgot the meeting of this, your Day; indeed, We have [accordingly] forgotten you. And taste the punishment of eternity for what you used to do.\"","tr":"Fathooqoo bima naseetum liqaayawmikum hatha inna naseenakum wathooqooAAathaba alkhuldi bima kuntum taAAmaloon","juz":21,"page":416},{"s":32,"a":15,"key":"32:15","ar":"إِنَّمَا يُؤْمِنُ بِـَٔايَـٰتِنَا ٱلَّذِينَ إِذَا ذُكِّرُوا۟ بِهَا خَرُّوا۟ سُجَّدًا وَسَبَّحُوا۟ بِحَمْدِ رَبِّهِمْ وَهُمْ لَا يَسْتَكْبِرُونَ ۩","en":"Only those believe in Our verses who, when they are reminded by them, fall down in prostration and exalt [Allāh] with praise of their Lord, and they are not arrogant.","tr":"Innama yu/minu bi-ayatinaallatheena itha thukkiroo bihakharroo sujjadan wasabbahoo bihamdi rabbihim wahumla yastakbiroon","juz":21,"page":416},{"s":32,"a":16,"key":"32:16","ar":"تَتَجَافَىٰ جُنُوبُهُمْ عَنِ ٱلْمَضَاجِعِ يَدْعُونَ رَبَّهُمْ خَوْفًا وَطَمَعًا وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَ","en":"Their sides part [i.e., they arise] from [their] beds; they supplicate their Lord in fear and aspiration, and from what We have provided them, they spend.1","tr":"Tatajafa junoobuhum AAani almadajiAAiyadAAoona rabbahum khawfan watamaAAan wamimmarazaqnahum yunfiqoon","juz":21,"page":416},{"s":32,"a":17,"key":"32:17","ar":"فَلَا تَعْلَمُ نَفْسٌ مَّآ أُخْفِىَ لَهُم مِّن قُرَّةِ أَعْيُنٍ جَزَآءًۢ بِمَا كَانُوا۟ يَعْمَلُونَ","en":"And no soul knows what has been hidden for them of comfort for eyes [i.e., satisfaction] as reward for what they used to do.","tr":"Fala taAAlamu nafsun maokhfiya lahum min qurrati aAAyunin jazaan bima kanooyaAAmaloon","juz":21,"page":416},{"s":32,"a":18,"key":"32:18","ar":"أَفَمَن كَانَ مُؤْمِنًا كَمَن كَانَ فَاسِقًا ۚ لَّا يَسْتَوُۥنَ","en":"Then is one who was a believer like one who was defiantly disobedient? They are not equal.","tr":"Afaman kana mu/minan kaman kanafasiqan la yastawoon","juz":21,"page":416},{"s":32,"a":19,"key":"32:19","ar":"أَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ فَلَهُمْ جَنَّـٰتُ ٱلْمَأْوَىٰ نُزُلًۢا بِمَا كَانُوا۟ يَعْمَلُونَ","en":"As for those who believed and did righteous deeds, for them will be the Gardens of Refuge as accommodation for what they used to do.","tr":"Amma allatheena amanoowaAAamiloo assalihati falahum jannatualma/wa nuzulan bima kanoo yaAAmaloon","juz":21,"page":416},{"s":32,"a":20,"key":"32:20","ar":"وَأَمَّا ٱلَّذِينَ فَسَقُوا۟ فَمَأْوَىٰهُمُ ٱلنَّارُ ۖ كُلَّمَآ أَرَادُوٓا۟ أَن يَخْرُجُوا۟ مِنْهَآ أُعِيدُوا۟ فِيهَا وَقِيلَ لَهُمْ ذُوقُوا۟ عَذَابَ ٱلنَّارِ ٱلَّذِى كُنتُم بِهِۦ تُكَذِّبُونَ","en":"But as for those who defiantly disobeyed, their refuge is the Fire. Every time they wish to emerge from it, they will be returned to it while it is said to them, \"Taste the punishment of the Fire which you used to deny.\"","tr":"Waamma allatheena fasaqoofama/wahumu annaru kullama aradooan yakhrujoo minha oAAeedoo feeha waqeela lahum thooqooAAathaba annari allathee kuntum bihitukaththiboon","juz":21,"page":416},{"s":32,"a":21,"key":"32:21","ar":"وَلَنُذِيقَنَّهُم مِّنَ ٱلْعَذَابِ ٱلْأَدْنَىٰ دُونَ ٱلْعَذَابِ ٱلْأَكْبَرِ لَعَلَّهُمْ يَرْجِعُونَ","en":"And We will surely let them taste the nearer punishment1 short of the greater punishment that perhaps they will return [i.e., repent].","tr":"Walanutheeqannahum mina alAAathabial-adna doona alAAathabi al-akbari laAAallahumyarjiAAoon","juz":21,"page":417},{"s":32,"a":22,"key":"32:22","ar":"وَمَنْ أَظْلَمُ مِمَّن ذُكِّرَ بِـَٔايَـٰتِ رَبِّهِۦ ثُمَّ أَعْرَضَ عَنْهَآ ۚ إِنَّا مِنَ ٱلْمُجْرِمِينَ مُنتَقِمُونَ","en":"And who is more unjust than one who is reminded of the verses of his Lord; then he turns away from them? Indeed We, from the criminals, will take retribution.","tr":"Waman athlamu mimman thukkirabi-ayati rabbihi thumma aAArada AAanhainna mina almujrimeena muntaqimoon","juz":21,"page":417},{"s":32,"a":23,"key":"32:23","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ فَلَا تَكُن فِى مِرْيَةٍ مِّن لِّقَآئِهِۦ ۖ وَجَعَلْنَـٰهُ هُدًى لِّبَنِىٓ إِسْرَٰٓءِيلَ","en":"And We certainly gave Moses the Scripture, so do not be in doubt over his meeting.1 And We made it [i.e., the Torah] guidance for the Children of Israel.","tr":"Walaqad atayna moosaalkitaba fala takun fee miryatin min liqa-ihiwajaAAalnahu hudan libanee isra-eel","juz":21,"page":417},{"s":32,"a":24,"key":"32:24","ar":"وَجَعَلْنَا مِنْهُمْ أَئِمَّةً يَهْدُونَ بِأَمْرِنَا لَمَّا صَبَرُوا۟ ۖ وَكَانُوا۟ بِـَٔايَـٰتِنَا يُوقِنُونَ","en":"And We made from among them leaders guiding by Our command when they were patient and [when] they were certain of Our signs.","tr":"WajaAAalna minhum a-immatan yahdoonabi-amrina lamma sabaroo wakanoo bi-ayatinayooqinoon","juz":21,"page":417},{"s":32,"a":25,"key":"32:25","ar":"إِنَّ رَبَّكَ هُوَ يَفْصِلُ بَيْنَهُمْ يَوْمَ ٱلْقِيَـٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ","en":"Indeed, your Lord will judge between them on the Day of Resurrection concerning that over which they used to differ.","tr":"Inna rabbaka huwa yafsilu baynahumyawma alqiyamati feema kanoo feehiyakhtalifoon","juz":21,"page":417},{"s":32,"a":26,"key":"32:26","ar":"أَوَلَمْ يَهْدِ لَهُمْ كَمْ أَهْلَكْنَا مِن قَبْلِهِم مِّنَ ٱلْقُرُونِ يَمْشُونَ فِى مَسَـٰكِنِهِمْ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ ۖ أَفَلَا يَسْمَعُونَ","en":"Has it not become clear to them how many generations We destroyed before them, [as] they walk among their dwellings? Indeed in that are signs; then do they not hear?","tr":"Awa lam yahdi lahum kam ahlakna minqablihim mina alqurooni yamshoona fee masakinihim inna feethalika laayatin afala yasmaAAoon","juz":21,"page":417},{"s":32,"a":27,"key":"32:27","ar":"أَوَلَمْ يَرَوْا۟ أَنَّا نَسُوقُ ٱلْمَآءَ إِلَى ٱلْأَرْضِ ٱلْجُرُزِ فَنُخْرِجُ بِهِۦ زَرْعًا تَأْكُلُ مِنْهُ أَنْعَـٰمُهُمْ وَأَنفُسُهُمْ ۖ أَفَلَا يُبْصِرُونَ","en":"Have they not seen that We drive water [in clouds] to barren land and bring forth thereby crops from which their livestock eat and [they] themselves? Then do they not see?","tr":"Awa lam yaraw anna nasooqu almaaila al-ardi aljuruzi fanukhriju bihi zarAAanta-kulu minhu anAAamuhum waanfusuhum afala yubsiroon","juz":21,"page":417},{"s":32,"a":28,"key":"32:28","ar":"وَيَقُولُونَ مَتَىٰ هَـٰذَا ٱلْفَتْحُ إِن كُنتُمْ صَـٰدِقِينَ","en":"And they say, \"When will be this conquest,1 if you should be truthful?\"","tr":"Wayaqooloona mata hatha alfathuin kuntum sadiqeen","juz":21,"page":417},{"s":32,"a":29,"key":"32:29","ar":"قُلْ يَوْمَ ٱلْفَتْحِ لَا يَنفَعُ ٱلَّذِينَ كَفَرُوٓا۟ إِيمَـٰنُهُمْ وَلَا هُمْ يُنظَرُونَ","en":"Say, [O Muḥammad], \"On the Day of Conquest the belief of those who had disbelieved will not benefit them, nor will they be reprieved.\"","tr":"Qul yawma alfathi la yanfaAAuallatheena kafaroo eemanuhum wala hum yuntharoon","juz":21,"page":417},{"s":32,"a":30,"key":"32:30","ar":"فَأَعْرِضْ عَنْهُمْ وَٱنتَظِرْ إِنَّهُم مُّنتَظِرُونَ","en":"So turn away from them and wait. Indeed, they are waiting.","tr":"FaaAArid AAanhum wantathirinnahum muntathiroon","juz":21,"page":417},{"s":33,"a":1,"key":"33:1","ar":" يَـٰٓأَيُّهَا ٱلنَّبِىُّ ٱتَّقِ ٱللَّهَ وَلَا تُطِعِ ٱلْكَـٰفِرِينَ وَٱلْمُنَـٰفِقِينَ ۗ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمًا","en":"O Prophet, fear Allāh and do not obey the disbelievers and the hypocrites. Indeed, Allāh is ever Knowing and Wise.","tr":"Ya ayyuha annabiyyuittaqi Allaha wala tutiAAi alkafireenawalmunafiqeena inna Allaha kanaAAaleeman hakeema","juz":21,"page":418},{"s":33,"a":2,"key":"33:2","ar":"وَٱتَّبِعْ مَا يُوحَىٰٓ إِلَيْكَ مِن رَّبِّكَ ۚ إِنَّ ٱللَّهَ كَانَ بِمَا تَعْمَلُونَ خَبِيرًا","en":"And follow that which is revealed to you from your Lord. Indeed Allāh is ever, of what you do, Aware.","tr":"WattabiAA ma yoohailayka min rabbika inna Allaha kana bimataAAmaloona khabeera","juz":21,"page":418},{"s":33,"a":3,"key":"33:3","ar":"وَتَوَكَّلْ عَلَى ٱللَّهِ ۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًا","en":"And rely upon Allāh; and sufficient is Allāh as Disposer of affairs.1","tr":"Watawakkal AAala Allahi wakafabillahi wakeela","juz":21,"page":418},{"s":33,"a":4,"key":"33:4","ar":"مَّا جَعَلَ ٱللَّهُ لِرَجُلٍ مِّن قَلْبَيْنِ فِى جَوْفِهِۦ ۚ وَمَا جَعَلَ أَزْوَٰجَكُمُ ٱلَّـٰٓـِٔى تُظَـٰهِرُونَ مِنْهُنَّ أُمَّهَـٰتِكُمْ ۚ وَمَا جَعَلَ أَدْعِيَآءَكُمْ أَبْنَآءَكُمْ ۚ ذَٰلِكُمْ قَوْلُكُم بِأَفْوَٰهِكُمْ ۖ وَٱللَّهُ يَقُولُ ٱلْحَقَّ وَهُوَ يَهْدِى ٱلسَّبِيلَ","en":"Allāh has not made for a man two hearts in his interior. And He has not made your wives whom you declare unlawful1 your mothers. And He has not made your claimed [i.e., adopted] sons your [true] sons. That is [merely] your saying by your mouths, but Allāh says the truth, and He guides to the [right] way.","tr":"Ma jaAAala Allahu lirajulin minqalbayni fee jawfihi wama jaAAala azwajakumu alla-eetuthahiroona minhunna ommahatikum wamajaAAala adAAiyaakum abnaakum thalikumqawlukum bi-afwahikum wallahu yaqoolu alhaqqawahuwa yahdee assabeel","juz":21,"page":418},{"s":33,"a":5,"key":"33:5","ar":"ٱدْعُوهُمْ لِـَٔابَآئِهِمْ هُوَ أَقْسَطُ عِندَ ٱللَّهِ ۚ فَإِن لَّمْ تَعْلَمُوٓا۟ ءَابَآءَهُمْ فَإِخْوَٰنُكُمْ فِى ٱلدِّينِ وَمَوَٰلِيكُمْ ۚ وَلَيْسَ عَلَيْكُمْ جُنَاحٌ فِيمَآ أَخْطَأْتُم بِهِۦ وَلَـٰكِن مَّا تَعَمَّدَتْ قُلُوبُكُمْ ۚ وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًا","en":"Call them1 by [the names of] their fathers; it is more just in the sight of Allāh. But if you do not know their fathers - then they are [still] your brothers in religion and those entrusted to you. And there is no blame upon you for that in which you have erred but [only for] what your hearts intended. And ever is Allāh Forgiving and Merciful.","tr":"OdAAoohum li-aba-ihim huwa aqsatuAAinda Allahi fa-in lam taAAlamoo abaahumfa-ikhwanukum fee addeeni wamawaleekumwalaysa AAalaykum junahun feema akhta/tumbihi walakin ma taAAammadat quloobukum wakanaAllahu ghafooran raheema","juz":21,"page":418},{"s":33,"a":6,"key":"33:6","ar":"ٱلنَّبِىُّ أَوْلَىٰ بِٱلْمُؤْمِنِينَ مِنْ أَنفُسِهِمْ ۖ وَأَزْوَٰجُهُۥٓ أُمَّهَـٰتُهُمْ ۗ وَأُو۟لُوا۟ ٱلْأَرْحَامِ بَعْضُهُمْ أَوْلَىٰ بِبَعْضٍ فِى كِتَـٰبِ ٱللَّهِ مِنَ ٱلْمُؤْمِنِينَ وَٱلْمُهَـٰجِرِينَ إِلَّآ أَن تَفْعَلُوٓا۟ إِلَىٰٓ أَوْلِيَآئِكُم مَّعْرُوفًا ۚ كَانَ ذَٰلِكَ فِى ٱلْكِتَـٰبِ مَسْطُورًا","en":"The Prophet is more worthy of the believers than themselves,1 and his wives are [in the position of] their mothers. And those of [blood] relationship are more entitled [to inheritance] in the decree of Allāh than the [other] believers and the emigrants, except that you may do to your close associates a kindness [through bequest]. That was in the Book2 inscribed.","tr":"Annabiyyu awla bilmu/mineenamin anfusihim waazwajuhu ommahatuhum waoloo al-arhamibaAAduhum awla bibaAAdin fee kitabiAllahi mina almu/mineena walmuhajireena illaan tafAAaloo ila awliya-ikum maAAroofan kanathalika fee alkitabi mastoora","juz":21,"page":418},{"s":33,"a":7,"key":"33:7","ar":"وَإِذْ أَخَذْنَا مِنَ ٱلنَّبِيِّـۧنَ مِيثَـٰقَهُمْ وَمِنكَ وَمِن نُّوحٍ وَإِبْرَٰهِيمَ وَمُوسَىٰ وَعِيسَى ٱبْنِ مَرْيَمَ ۖ وَأَخَذْنَا مِنْهُم مِّيثَـٰقًا غَلِيظًا","en":"And [mention, O Muḥammad], when We took from the prophets their covenant and from you and from Noah and Abraham and Moses and Jesus, the son of Mary; and We took from them a solemn covenant","tr":"Wa-ith akhathna mina annabiyyeenameethaqahum waminka wamin noohin wa-ibraheemawamoosa waAAeesa ibni maryama waakhathnaminhum meethaqan ghaleetha","juz":21,"page":419},{"s":33,"a":8,"key":"33:8","ar":"لِّيَسْـَٔلَ ٱلصَّـٰدِقِينَ عَن صِدْقِهِمْ ۚ وَأَعَدَّ لِلْكَـٰفِرِينَ عَذَابًا أَلِيمًا","en":"That He may question the truthful about their truth.1 And He has prepared for the disbelievers a painful punishment.","tr":"Liyas-ala assadiqeena AAan sidqihimwaaAAadda lilkafireena AAathaban aleema","juz":21,"page":419},{"s":33,"a":9,"key":"33:9","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱذْكُرُوا۟ نِعْمَةَ ٱللَّهِ عَلَيْكُمْ إِذْ جَآءَتْكُمْ جُنُودٌ فَأَرْسَلْنَا عَلَيْهِمْ رِيحًا وَجُنُودًا لَّمْ تَرَوْهَا ۚ وَكَانَ ٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرًا","en":"O you who have believed, remember the favor of Allāh upon you when armies came to [attack] you and We sent upon them a wind and armies [of angels] you did not see. And ever is Allāh, of what you do, Seeing.","tr":"Ya ayyuha allatheena amanooothkuroo niAAmata Allahi AAalaykum ith jaatkumjunoodun faarsalna AAalayhim reehan wajunoodan lamtarawha wakana Allahu bimataAAmaloona baseera","juz":21,"page":419},{"s":33,"a":10,"key":"33:10","ar":"إِذْ جَآءُوكُم مِّن فَوْقِكُمْ وَمِنْ أَسْفَلَ مِنكُمْ وَإِذْ زَاغَتِ ٱلْأَبْصَـٰرُ وَبَلَغَتِ ٱلْقُلُوبُ ٱلْحَنَاجِرَ وَتَظُنُّونَ بِٱللَّهِ ٱلظُّنُونَا۠","en":"[Remember] when they came at you from above you and from below you, and when eyes shifted [in fear], and hearts reached the throats, and you assumed about Allāh [various] assumptions.","tr":"Ith jaookum min fawqikum waminasfala minkum wa-ith zaghati al-absaruwabalaghati alquloobu alhanajira watathunnoonabillahi aththunoona","juz":21,"page":419},{"s":33,"a":11,"key":"33:11","ar":"هُنَالِكَ ٱبْتُلِىَ ٱلْمُؤْمِنُونَ وَزُلْزِلُوا۟ زِلْزَالًا شَدِيدًا","en":"There the believers were tested and shaken with a severe shaking.","tr":"Hunalika ibtuliya almu-minoonawazulziloo zilzalan shadeeda","juz":21,"page":419},{"s":33,"a":12,"key":"33:12","ar":"وَإِذْ يَقُولُ ٱلْمُنَـٰفِقُونَ وَٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌ مَّا وَعَدَنَا ٱللَّهُ وَرَسُولُهُۥٓ إِلَّا غُرُورًا","en":"And [remember] when the hypocrites and those in whose hearts is disease said, \"Allāh and His Messenger did not promise us except delusion,\"","tr":"Wa-ith yaqoolu almunafiqoonawallatheena fee quloobihim maradun mawaAAadana Allahu warasooluhu illa ghuroora","juz":21,"page":419},{"s":33,"a":13,"key":"33:13","ar":"وَإِذْ قَالَت طَّآئِفَةٌ مِّنْهُمْ يَـٰٓأَهْلَ يَثْرِبَ لَا مُقَامَ لَكُمْ فَٱرْجِعُوا۟ ۚ وَيَسْتَـْٔذِنُ فَرِيقٌ مِّنْهُمُ ٱلنَّبِىَّ يَقُولُونَ إِنَّ بُيُوتَنَا عَوْرَةٌ وَمَا هِىَ بِعَوْرَةٍ ۖ إِن يُرِيدُونَ إِلَّا فِرَارًا","en":"And when a faction of them said, \"O people of Yathrib,1 there is no stability for you [here], so return [home].\" And a party of them asked permission of the Prophet, saying, \"Indeed, our houses are exposed [i.e., unprotected],\" while they were not exposed. They did not intend except to flee.","tr":"Wa-ith qalat ta-ifatunminhum ya ahla yathriba la muqama lakum farjiAAoowayasta/thinu fareequn minhumu annabiyyayaqooloona inna buyootana AAawratun wama hiyabiAAawratin in yureedoona illa firara","juz":21,"page":419},{"s":33,"a":14,"key":"33:14","ar":"وَلَوْ دُخِلَتْ عَلَيْهِم مِّنْ أَقْطَارِهَا ثُمَّ سُئِلُوا۟ ٱلْفِتْنَةَ لَـَٔاتَوْهَا وَمَا تَلَبَّثُوا۟ بِهَآ إِلَّا يَسِيرًا","en":"And if they had been entered upon from all its [surrounding] regions and fitnah [i.e., disbelief] had been demanded of them, they would have done it and not hesitated over it except briefly.","tr":"Walaw dukhilat AAalayhim min aqtarihathumma su-iloo alfitnata laatawha wamatalabbathoo biha illa yaseera","juz":21,"page":419},{"s":33,"a":15,"key":"33:15","ar":"وَلَقَدْ كَانُوا۟ عَـٰهَدُوا۟ ٱللَّهَ مِن قَبْلُ لَا يُوَلُّونَ ٱلْأَدْبَـٰرَ ۚ وَكَانَ عَهْدُ ٱللَّهِ مَسْـُٔولًا","en":"And they had already promised Allāh before not to turn their backs [i.e., flee]. And ever is the promise to Allāh [that about which one will be] questioned.","tr":"Walaqad kanoo AAahadoo Allahamin qablu la yuwalloona al-adbara wakanaAAahdu Allahi mas-oola","juz":21,"page":419},{"s":33,"a":16,"key":"33:16","ar":"قُل لَّن يَنفَعَكُمُ ٱلْفِرَارُ إِن فَرَرْتُم مِّنَ ٱلْمَوْتِ أَوِ ٱلْقَتْلِ وَإِذًا لَّا تُمَتَّعُونَ إِلَّا قَلِيلًا","en":"Say, [O Muḥammad], \"Never will fleeing benefit you if you should flee from death or killing; and then [if you did], you would not be given enjoyment [of life] except for a little.\"","tr":"Qul lan yanfaAAakumu alfiraru infarartum mina almawti awi alqatli wa-ithan latumattaAAoona illa qaleela","juz":21,"page":420},{"s":33,"a":17,"key":"33:17","ar":"قُلْ مَن ذَا ٱلَّذِى يَعْصِمُكُم مِّنَ ٱللَّهِ إِنْ أَرَادَ بِكُمْ سُوٓءًا أَوْ أَرَادَ بِكُمْ رَحْمَةً ۚ وَلَا يَجِدُونَ لَهُم مِّن دُونِ ٱللَّهِ وَلِيًّا وَلَا نَصِيرًا","en":"Say, \"Who is it that can protect you from Allāh1 if He intends for you an ill or intends for you a mercy?\" And they will not find for themselves besides Allāh any protector or any helper.","tr":"Qul man tha allathee yaAAsimukummina Allahi in arada bikum soo-an aw aradabikum rahmatan wala yajidoona lahum min dooni Allahiwaliyyan wala naseera","juz":21,"page":420},{"s":33,"a":18,"key":"33:18","ar":"۞ قَدْ يَعْلَمُ ٱللَّهُ ٱلْمُعَوِّقِينَ مِنكُمْ وَٱلْقَآئِلِينَ لِإِخْوَٰنِهِمْ هَلُمَّ إِلَيْنَا ۖ وَلَا يَأْتُونَ ٱلْبَأْسَ إِلَّا قَلِيلًا","en":"Already Allāh knows the hinderers1 among you and those [hypocrites] who say to their brothers, \"Come to us,\"2 and do not go to battle, except for a few,3","tr":"Qad yaAAlamu Allahu almuAAawwiqeenaminkum walqa-ileena li-ikhwanihim halummailayna wala ya/toona alba/sa illa qaleela","juz":21,"page":420},{"s":33,"a":19,"key":"33:19","ar":"أَشِحَّةً عَلَيْكُمْ ۖ فَإِذَا جَآءَ ٱلْخَوْفُ رَأَيْتَهُمْ يَنظُرُونَ إِلَيْكَ تَدُورُ أَعْيُنُهُمْ كَٱلَّذِى يُغْشَىٰ عَلَيْهِ مِنَ ٱلْمَوْتِ ۖ فَإِذَا ذَهَبَ ٱلْخَوْفُ سَلَقُوكُم بِأَلْسِنَةٍ حِدَادٍ أَشِحَّةً عَلَى ٱلْخَيْرِ ۚ أُو۟لَـٰٓئِكَ لَمْ يُؤْمِنُوا۟ فَأَحْبَطَ ٱللَّهُ أَعْمَـٰلَهُمْ ۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرًا","en":"Indisposed1 toward you. And when fear comes, you see them looking at you, their eyes revolving like one being overcome by death. But when fear departs, they lash you with sharp tongues, indisposed toward [any] good. Those have not believed, so Allāh has rendered their deeds worthless, and ever is that, for Allāh, easy.","tr":"Ashihhatan AAalaykum fa-itha jaaalkhawfu raaytahum yanthuroona ilayka tadooruaAAyunuhum kallathee yughsha AAalayhi minaalmawti fa-itha thahaba alkhawfu salaqookumbi-alsinatin hidadin ashihhatan AAalaalkhayri ola-ika lam yu/minoo faahbata AllahuaAAmalahum wakana thalika AAala Allahiyaseera","juz":21,"page":420},{"s":33,"a":20,"key":"33:20","ar":"يَحْسَبُونَ ٱلْأَحْزَابَ لَمْ يَذْهَبُوا۟ ۖ وَإِن يَأْتِ ٱلْأَحْزَابُ يَوَدُّوا۟ لَوْ أَنَّهُم بَادُونَ فِى ٱلْأَعْرَابِ يَسْـَٔلُونَ عَنْ أَنۢبَآئِكُمْ ۖ وَلَوْ كَانُوا۟ فِيكُم مَّا قَـٰتَلُوٓا۟ إِلَّا قَلِيلًا","en":"They think the companies have not [yet] withdrawn.1 And if the companies should come [again], they would wish they were in the desert among the bedouins, inquiring [from afar] about your news. And if they should be among you, they would not fight except for a little.","tr":"Yahsaboona al-ahzabalam yathhaboo wa-in ya/ti al-ahzabu yawaddoolaw annahum badoona fee al-aAArabi yas-aloona AAananba-ikum walaw kanoo feekum ma qatalooilla qaleela","juz":21,"page":420},{"s":33,"a":21,"key":"33:21","ar":"لَّقَدْ كَانَ لَكُمْ فِى رَسُولِ ٱللَّهِ أُسْوَةٌ حَسَنَةٌ لِّمَن كَانَ يَرْجُوا۟ ٱللَّهَ وَٱلْيَوْمَ ٱلْـَٔاخِرَ وَذَكَرَ ٱللَّهَ كَثِيرًا","en":"There has certainly been for you in the Messenger of Allāh an excellent pattern1 for anyone whose hope is in Allāh and the Last Day and [who] remembers Allāh often.","tr":"Laqad kana lakum fee rasooli Allahioswatun hasanatun liman kana yarjoo Allahawalyawma al-akhira wathakara Allahakatheera","juz":21,"page":420},{"s":33,"a":22,"key":"33:22","ar":"وَلَمَّا رَءَا ٱلْمُؤْمِنُونَ ٱلْأَحْزَابَ قَالُوا۟ هَـٰذَا مَا وَعَدَنَا ٱللَّهُ وَرَسُولُهُۥ وَصَدَقَ ٱللَّهُ وَرَسُولُهُۥ ۚ وَمَا زَادَهُمْ إِلَّآ إِيمَـٰنًا وَتَسْلِيمًا","en":"And when the believers saw the companies, they said, \"This is what Allāh and His Messenger had promised us, and Allāh and His Messenger spoke the truth.\" And it increased them only in faith and acceptance.","tr":"Walamma raa almu/minoona al-ahzabaqaloo hatha ma waAAadana Allahuwarasooluhu wasadaqa Allahu warasooluhu wamazadahum illa eemanan watasleema","juz":21,"page":420},{"s":33,"a":23,"key":"33:23","ar":"مِّنَ ٱلْمُؤْمِنِينَ رِجَالٌ صَدَقُوا۟ مَا عَـٰهَدُوا۟ ٱللَّهَ عَلَيْهِ ۖ فَمِنْهُم مَّن قَضَىٰ نَحْبَهُۥ وَمِنْهُم مَّن يَنتَظِرُ ۖ وَمَا بَدَّلُوا۟ تَبْدِيلًا","en":"Among the believers are men true to what they promised Allāh. Among them is he who has fulfilled his vow [to the death], and among them is he who awaits [his chance]. And they did not alter [the terms of their commitment] by any alteration -","tr":"Mina almu/mineena rijalun sadaqooma AAahadoo Allaha AAalayhi faminhum man qadanahbahu waminhum man yantathiru wamabaddaloo tabdeela","juz":21,"page":421},{"s":33,"a":24,"key":"33:24","ar":"لِّيَجْزِىَ ٱللَّهُ ٱلصَّـٰدِقِينَ بِصِدْقِهِمْ وَيُعَذِّبَ ٱلْمُنَـٰفِقِينَ إِن شَآءَ أَوْ يَتُوبَ عَلَيْهِمْ ۚ إِنَّ ٱللَّهَ كَانَ غَفُورًا رَّحِيمًا","en":"That Allāh may reward the truthful for their truth and punish the hypocrites if He wills or accept their repentance. Indeed, Allāh is ever Forgiving and Merciful.","tr":"Liyajziya Allahu assadiqeenabisidqihim wayuAAaththiba almunafiqeena inshaa aw yatooba AAalayhim inna Allaha kanaghafooran raheema","juz":21,"page":421},{"s":33,"a":25,"key":"33:25","ar":"وَرَدَّ ٱللَّهُ ٱلَّذِينَ كَفَرُوا۟ بِغَيْظِهِمْ لَمْ يَنَالُوا۟ خَيْرًا ۚ وَكَفَى ٱللَّهُ ٱلْمُؤْمِنِينَ ٱلْقِتَالَ ۚ وَكَانَ ٱللَّهُ قَوِيًّا عَزِيزًا","en":"And Allāh repelled those who disbelieved, in their rage, not having obtained any good. And sufficient was Allāh for the believers in battle, and ever is Allāh Powerful and Exalted in Might.","tr":"Waradda Allahu allatheenakafaroo bighaythihim lam yanaloo khayranwakafa Allahu almu/mineena alqitala wakanaAllahu qawiyyan AAazeeza","juz":21,"page":421},{"s":33,"a":26,"key":"33:26","ar":"وَأَنزَلَ ٱلَّذِينَ ظَـٰهَرُوهُم مِّنْ أَهْلِ ٱلْكِتَـٰبِ مِن صَيَاصِيهِمْ وَقَذَفَ فِى قُلُوبِهِمُ ٱلرُّعْبَ فَرِيقًا تَقْتُلُونَ وَتَأْسِرُونَ فَرِيقًا","en":"And He brought down those who supported them among the People of the Scripture1 from their fortresses and cast terror into their hearts [so that] a party [i.e., their men] you killed, and you took captive a party [i.e., the women and children].","tr":"Waanzala allatheena thaharoohummin ahli alkitabi min sayaseehim waqathafafee quloobihimu arruAAba fareeqan taqtuloona wata/siroonafareeqa","juz":21,"page":421},{"s":33,"a":27,"key":"33:27","ar":"وَأَوْرَثَكُمْ أَرْضَهُمْ وَدِيَـٰرَهُمْ وَأَمْوَٰلَهُمْ وَأَرْضًا لَّمْ تَطَـُٔوهَا ۚ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرًا","en":"And He caused you to inherit their land and their homes and their properties and a land which you have not trodden.1 And ever is Allāh, over all things, competent.","tr":"Waawrathakum ardahum wadiyarahumwaamwalahum waardan lam tataooha wakanaAllahu AAala kulli shay-in qadeera","juz":21,"page":421},{"s":33,"a":28,"key":"33:28","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ قُل لِّأَزْوَٰجِكَ إِن كُنتُنَّ تُرِدْنَ ٱلْحَيَوٰةَ ٱلدُّنْيَا وَزِينَتَهَا فَتَعَالَيْنَ أُمَتِّعْكُنَّ وَأُسَرِّحْكُنَّ سَرَاحًا جَمِيلًا","en":"O Prophet, say to your wives, \"If you should desire the worldly life and its adornment, then come, I will provide for you and give you a gracious release.","tr":"Ya ayyuha annabiyyuqul li-azwajika in kuntunna turidna alhayataaddunya wazeenataha fataAAalaynaomattiAAkunna waosarrihkunna sarahan jameela","juz":21,"page":421},{"s":33,"a":29,"key":"33:29","ar":"وَإِن كُنتُنَّ تُرِدْنَ ٱللَّهَ وَرَسُولَهُۥ وَٱلدَّارَ ٱلْـَٔاخِرَةَ فَإِنَّ ٱللَّهَ أَعَدَّ لِلْمُحْسِنَـٰتِ مِنكُنَّ أَجْرًا عَظِيمًا","en":"But if you should desire Allāh and His Messenger and the home of the Hereafter - then indeed, Allāh has prepared for the doers of good among you a great reward.\"","tr":"Wa-in kuntunna turidna Allahawarasoolahu waddara al-akhirata fa-innaAllaha aAAadda lilmuhsinati minkunna ajranAAatheema","juz":21,"page":421},{"s":33,"a":30,"key":"33:30","ar":"يَـٰنِسَآءَ ٱلنَّبِىِّ مَن يَأْتِ مِنكُنَّ بِفَـٰحِشَةٍ مُّبَيِّنَةٍ يُضَـٰعَفْ لَهَا ٱلْعَذَابُ ضِعْفَيْنِ ۚ وَكَانَ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرًا","en":"O wives of the Prophet, whoever of you should commit a clear immorality - for her the punishment would be doubled two fold, and ever is that, for Allāh, easy.","tr":"Ya nisaa annabiyyi manya/ti minkunna bifahishatin mubayyinatin yudaAAaflaha alAAathabu diAAfayni wakana thalikaAAala Allahi yaseera","juz":21,"page":421},{"s":33,"a":31,"key":"33:31","ar":"۞ وَمَن يَقْنُتْ مِنكُنَّ لِلَّهِ وَرَسُولِهِۦ وَتَعْمَلْ صَـٰلِحًا نُّؤْتِهَآ أَجْرَهَا مَرَّتَيْنِ وَأَعْتَدْنَا لَهَا رِزْقًا كَرِيمًا","en":"And whoever of you devoutly obeys Allāh and His Messenger and does righteousness - We will give her her reward twice; and We have prepared for her a noble provision.","tr":"Waman yaqnut minkunna lillahiwarasoolihi wataAAmal salihan nu/tiha ajrahamarratayni waaAAtadna laha rizqan kareema","juz":22,"page":422},{"s":33,"a":32,"key":"33:32","ar":"يَـٰنِسَآءَ ٱلنَّبِىِّ لَسْتُنَّ كَأَحَدٍ مِّنَ ٱلنِّسَآءِ ۚ إِنِ ٱتَّقَيْتُنَّ فَلَا تَخْضَعْنَ بِٱلْقَوْلِ فَيَطْمَعَ ٱلَّذِى فِى قَلْبِهِۦ مَرَضٌ وَقُلْنَ قَوْلًا مَّعْرُوفًا","en":"O wives of the Prophet, you are not like anyone among women. If you fear Allāh, then do not be soft in speech [to men],1 lest he in whose heart is disease should covet, but speak with appropriate speech.","tr":"Ya nisaa annabiyyilastunna kaahadin mina annisa-i iniittaqaytunna fala takhdaAAna bilqawli fayatmaAAaallathee fee qalbihi maradun waqulna qawlanmaAAroofa","juz":22,"page":422},{"s":33,"a":33,"key":"33:33","ar":"وَقَرْنَ فِى بُيُوتِكُنَّ وَلَا تَبَرَّجْنَ تَبَرُّجَ ٱلْجَـٰهِلِيَّةِ ٱلْأُولَىٰ ۖ وَأَقِمْنَ ٱلصَّلَوٰةَ وَءَاتِينَ ٱلزَّكَوٰةَ وَأَطِعْنَ ٱللَّهَ وَرَسُولَهُۥٓ ۚ إِنَّمَا يُرِيدُ ٱللَّهُ لِيُذْهِبَ عَنكُمُ ٱلرِّجْسَ أَهْلَ ٱلْبَيْتِ وَيُطَهِّرَكُمْ تَطْهِيرًا","en":"And abide in your houses and do not display yourselves as [was] the display of the former times of ignorance. And establish prayer and give zakāh and obey Allāh and His Messenger. Allāh intends only to remove from you the impurity [of sin], O people of the [Prophet's] household, and to purify you with [extensive] purification.","tr":"Waqarna fee buyootikunna walatabarrajna tabarruja aljahiliyyati al-oola waaqimnaassalata waateena azzakatawaatiAAna Allaha warasoolahu innama yureeduAllahu liyuthhiba AAankumu arrijsa ahlaalbayti wayutahhirakum tatheera","juz":22,"page":422},{"s":33,"a":34,"key":"33:34","ar":"وَٱذْكُرْنَ مَا يُتْلَىٰ فِى بُيُوتِكُنَّ مِنْ ءَايَـٰتِ ٱللَّهِ وَٱلْحِكْمَةِ ۚ إِنَّ ٱللَّهَ كَانَ لَطِيفًا خَبِيرًا","en":"And remember what is recited in your houses of the verses of Allāh and wisdom.1 Indeed, Allāh is ever Subtle2 and Aware.","tr":"Wathkurna ma yutlafee buyootikunna min ayati Allahi walhikmatiinna Allaha kana lateefan khabeera","juz":22,"page":422},{"s":33,"a":35,"key":"33:35","ar":"إِنَّ ٱلْمُسْلِمِينَ وَٱلْمُسْلِمَـٰتِ وَٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَـٰتِ وَٱلْقَـٰنِتِينَ وَٱلْقَـٰنِتَـٰتِ وَٱلصَّـٰدِقِينَ وَٱلصَّـٰدِقَـٰتِ وَٱلصَّـٰبِرِينَ وَٱلصَّـٰبِرَٰتِ وَٱلْخَـٰشِعِينَ وَٱلْخَـٰشِعَـٰتِ وَٱلْمُتَصَدِّقِينَ وَٱلْمُتَصَدِّقَـٰتِ وَٱلصَّـٰٓئِمِينَ وَٱلصَّـٰٓئِمَـٰتِ وَٱلْحَـٰفِظِينَ فُرُوجَهُمْ وَٱلْحَـٰفِظَـٰتِ وَٱلذَّٰكِرِينَ ٱللَّهَ كَثِيرًا وَٱلذَّٰكِرَٰتِ أَعَدَّ ٱللَّهُ لَهُم مَّغْفِرَةً وَأَجْرًا عَظِيمًا","en":"Indeed, the Muslim men and Muslim women, the believing men and believing women, the obedient men and obedient women, the truthful men and truthful women, the patient men and patient women, the humble men and humble women, the charitable men and charitable women, the fasting men and fasting women, the men who guard their private parts and the women who do so, and the men who remember Allāh often and the women who do so - for them Allāh has prepared forgiveness and a great reward.","tr":"Inna almuslimeena walmuslimatiwalmu/mineena walmu/minati walqaniteenawalqanitati wassadiqeena wassadiqatiwassabireena wassabiratiwalkhashiAAeena walkhashiAAatiwalmutasaddiqeena walmutasaddiqatiwassa-imeena wassa-imatiwalhafitheena furoojahum walhafithatiwaththakireena Allaha katheeran waththakiratiaAAadda Allahu lahum maghfiratan waajran AAatheema","juz":22,"page":422},{"s":33,"a":36,"key":"33:36","ar":"وَمَا كَانَ لِمُؤْمِنٍ وَلَا مُؤْمِنَةٍ إِذَا قَضَى ٱللَّهُ وَرَسُولُهُۥٓ أَمْرًا أَن يَكُونَ لَهُمُ ٱلْخِيَرَةُ مِنْ أَمْرِهِمْ ۗ وَمَن يَعْصِ ٱللَّهَ وَرَسُولَهُۥ فَقَدْ ضَلَّ ضَلَـٰلًا مُّبِينًا","en":"It is not for a believing man or a believing woman, when Allāh and His Messenger have decided a matter, that they should [thereafter] have any choice about their affair. And whoever disobeys Allāh and His Messenger has certainly strayed into clear error.","tr":"Wama kana limu/minin walamu/minatin itha qada Allahu warasooluhuamran an yakoona lahumu alkhiyaratu min amrihim waman yaAAsiAllaha warasoolahu faqad dalla dalalanmubeena","juz":22,"page":423},{"s":33,"a":37,"key":"33:37","ar":"وَإِذْ تَقُولُ لِلَّذِىٓ أَنْعَمَ ٱللَّهُ عَلَيْهِ وَأَنْعَمْتَ عَلَيْهِ أَمْسِكْ عَلَيْكَ زَوْجَكَ وَٱتَّقِ ٱللَّهَ وَتُخْفِى فِى نَفْسِكَ مَا ٱللَّهُ مُبْدِيهِ وَتَخْشَى ٱلنَّاسَ وَٱللَّهُ أَحَقُّ أَن تَخْشَىٰهُ ۖ فَلَمَّا قَضَىٰ زَيْدٌ مِّنْهَا وَطَرًا زَوَّجْنَـٰكَهَا لِكَىْ لَا يَكُونَ عَلَى ٱلْمُؤْمِنِينَ حَرَجٌ فِىٓ أَزْوَٰجِ أَدْعِيَآئِهِمْ إِذَا قَضَوْا۟ مِنْهُنَّ وَطَرًا ۚ وَكَانَ أَمْرُ ٱللَّهِ مَفْعُولًا","en":"And [remember, O Muḥammad], when you said to the one on whom Allāh bestowed favor and you bestowed favor,1 \"Keep your wife and fear Allāh,\" while you concealed within yourself that which Allāh is to disclose.2 And you feared the people,3 while Allāh has more right that you fear Him.4 So when Zayd had no longer any need for her, We married her to you in order that there not be upon the believers any discomfort [i.e., guilt] concerning the wives of their claimed [i.e., adopted] sons when they no longer have need of them. And ever is the command [i.e., decree] of Allāh accomplished.","tr":"Wa-ith taqoolu lillatheeanAAama Allahu AAalayhi waanAAamta AAalayhi amsik AAalaykazawjaka wattaqi Allaha watukhfee fee nafsika maAllahu mubdeehi watakhsha annasa wallahuahaqqu an takhshahu falamma qadazaydun minha wataran zawwajnakahalikay la yakoona AAala almu/mineena harajunfee azwaji adAAiya-ihim itha qadawminhunna wataran wakana amru Allahi mafAAoola","juz":22,"page":423},{"s":33,"a":38,"key":"33:38","ar":"مَّا كَانَ عَلَى ٱلنَّبِىِّ مِنْ حَرَجٍ فِيمَا فَرَضَ ٱللَّهُ لَهُۥ ۖ سُنَّةَ ٱللَّهِ فِى ٱلَّذِينَ خَلَوْا۟ مِن قَبْلُ ۚ وَكَانَ أَمْرُ ٱللَّهِ قَدَرًا مَّقْدُورًا","en":"There is not to be upon the Prophet any discomfort concerning that which Allāh has imposed upon him.1 [This is] the established way of Allāh with those [prophets] who have passed on before. And ever is the command of Allāh a destiny decreed.","tr":"Ma kana AAala annabiyyimin harajin feema farada Allahu lahusunnata Allahi fee allatheena khalaw min qablu wakanaamru Allahi qadaran maqdoora","juz":22,"page":423},{"s":33,"a":39,"key":"33:39","ar":"ٱلَّذِينَ يُبَلِّغُونَ رِسَـٰلَـٰتِ ٱللَّهِ وَيَخْشَوْنَهُۥ وَلَا يَخْشَوْنَ أَحَدًا إِلَّا ٱللَّهَ ۗ وَكَفَىٰ بِٱللَّهِ حَسِيبًا","en":"[Allāh praises] those who convey the messages of Allāh1 and fear Him and do not fear anyone but Allāh. And sufficient is Allāh as Accountant.","tr":"Allatheena yuballighoona risalatiAllahi wayakhshawnahu wala yakhshawna ahadanilla Allaha wakafa billahi haseeba","juz":22,"page":423},{"s":33,"a":40,"key":"33:40","ar":"مَّا كَانَ مُحَمَّدٌ أَبَآ أَحَدٍ مِّن رِّجَالِكُمْ وَلَـٰكِن رَّسُولَ ٱللَّهِ وَخَاتَمَ ٱلنَّبِيِّـۧنَ ۗ وَكَانَ ٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمًا","en":"Muḥammad is not the father of [any] one of your men, but [he is] the Messenger of Allāh and seal [i.e., last] of the prophets. And ever is Allāh, of all things, Knowing.","tr":"Ma kana muhammadun abaahadin min rijalikum walakin rasoola Allahiwakhatama annabiyyeena wakana Allahubikulli shay-in AAaleema","juz":22,"page":423},{"s":33,"a":41,"key":"33:41","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱذْكُرُوا۟ ٱللَّهَ ذِكْرًا كَثِيرًا","en":"O you who have believed, remember Allāh with much remembrance","tr":"Ya ayyuha allatheena amanooothkuroo Allaha thikran katheera","juz":22,"page":423},{"s":33,"a":42,"key":"33:42","ar":"وَسَبِّحُوهُ بُكْرَةً وَأَصِيلًا","en":"And exalt Him morning and afternoon.","tr":"Wasabbihoohu bukratan waaseela","juz":22,"page":423},{"s":33,"a":43,"key":"33:43","ar":"هُوَ ٱلَّذِى يُصَلِّى عَلَيْكُمْ وَمَلَـٰٓئِكَتُهُۥ لِيُخْرِجَكُم مِّنَ ٱلظُّلُمَـٰتِ إِلَى ٱلنُّورِ ۚ وَكَانَ بِٱلْمُؤْمِنِينَ رَحِيمًا","en":"It is He who confers blessing upon you,1 and His angels [ask Him to do so] that He may bring you out from darknesses into the light. And ever is He, to the believers, Merciful.","tr":"Huwa allathee yusalleeAAalaykum wamala-ikatuhu liyukhrijakum mina aththulumatiila annoori wakana bilmu/mineena raheema","juz":22,"page":423},{"s":33,"a":44,"key":"33:44","ar":"تَحِيَّتُهُمْ يَوْمَ يَلْقَوْنَهُۥ سَلَـٰمٌ ۚ وَأَعَدَّ لَهُمْ أَجْرًا كَرِيمًا","en":"Their greeting the Day they meet Him will be, \"Peace.\" And He has prepared for them a noble reward.","tr":"Tahiyyatuhum yawma yalqawnahu salamunwaaAAadda lahum ajran kareema","juz":22,"page":424},{"s":33,"a":45,"key":"33:45","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ إِنَّآ أَرْسَلْنَـٰكَ شَـٰهِدًا وَمُبَشِّرًا وَنَذِيرًا","en":"O Prophet, indeed We have sent you as a witness and a bringer of good tidings and a warner","tr":"Ya ayyuha annabiyyuinna arsalnaka shahidan wamubashshiran wanatheera","juz":22,"page":424},{"s":33,"a":46,"key":"33:46","ar":"وَدَاعِيًا إِلَى ٱللَّهِ بِإِذْنِهِۦ وَسِرَاجًا مُّنِيرًا","en":"And one who invites to Allāh, by His permission, and an illuminating lamp.","tr":"WadaAAiyan ila Allahibi-ithnihi wasirajan muneera","juz":22,"page":424},{"s":33,"a":47,"key":"33:47","ar":"وَبَشِّرِ ٱلْمُؤْمِنِينَ بِأَنَّ لَهُم مِّنَ ٱللَّهِ فَضْلًا كَبِيرًا","en":"And give good tidings to the believers that they will have from Allāh great bounty.","tr":"Wabashshiri almu/mineena bi-anna lahum minaAllahi fadlan kabeera","juz":22,"page":424},{"s":33,"a":48,"key":"33:48","ar":"وَلَا تُطِعِ ٱلْكَـٰفِرِينَ وَٱلْمُنَـٰفِقِينَ وَدَعْ أَذَىٰهُمْ وَتَوَكَّلْ عَلَى ٱللَّهِ ۚ وَكَفَىٰ بِٱللَّهِ وَكِيلًا","en":"And do not obey the disbelievers and the hypocrites and disregard their annoyance, and rely upon Allāh. And sufficient is Allāh as Disposer of affairs.","tr":"Wala tutiAAi alkafireenawalmunafiqeena wadaAA athahum watawakkalAAala Allahi wakafa billahiwakeela","juz":22,"page":424},{"s":33,"a":49,"key":"33:49","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا نَكَحْتُمُ ٱلْمُؤْمِنَـٰتِ ثُمَّ طَلَّقْتُمُوهُنَّ مِن قَبْلِ أَن تَمَسُّوهُنَّ فَمَا لَكُمْ عَلَيْهِنَّ مِنْ عِدَّةٍ تَعْتَدُّونَهَا ۖ فَمَتِّعُوهُنَّ وَسَرِّحُوهُنَّ سَرَاحًا جَمِيلًا","en":"O you who have believed, when you marry believing women and then divorce them before you have touched them [i.e., consummated the marriage], then there is not for you any waiting period to count concerning them. So provide for them and give them a gracious release.","tr":"Ya ayyuha allatheena amanooitha nakahtumu almu/minati thumma tallaqtumoohunnamin qabli an tamassoohunna fama lakum AAalayhinna minAAiddatin taAAtaddoonaha famattiAAoohunna wasarrihoohunnasarahan jameela","juz":22,"page":424},{"s":33,"a":50,"key":"33:50","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ إِنَّآ أَحْلَلْنَا لَكَ أَزْوَٰجَكَ ٱلَّـٰتِىٓ ءَاتَيْتَ أُجُورَهُنَّ وَمَا مَلَكَتْ يَمِينُكَ مِمَّآ أَفَآءَ ٱللَّهُ عَلَيْكَ وَبَنَاتِ عَمِّكَ وَبَنَاتِ عَمَّـٰتِكَ وَبَنَاتِ خَالِكَ وَبَنَاتِ خَـٰلَـٰتِكَ ٱلَّـٰتِى هَاجَرْنَ مَعَكَ وَٱمْرَأَةً مُّؤْمِنَةً إِن وَهَبَتْ نَفْسَهَا لِلنَّبِىِّ إِنْ أَرَادَ ٱلنَّبِىُّ أَن يَسْتَنكِحَهَا خَالِصَةً لَّكَ مِن دُونِ ٱلْمُؤْمِنِينَ ۗ قَدْ عَلِمْنَا مَا فَرَضْنَا عَلَيْهِمْ فِىٓ أَزْوَٰجِهِمْ وَمَا مَلَكَتْ أَيْمَـٰنُهُمْ لِكَيْلَا يَكُونَ عَلَيْكَ حَرَجٌ ۗ وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًا","en":"O Prophet, indeed We have made lawful to you your wives to whom you have given their due compensation1 and those your right hand possesses from what Allāh has returned to you [of captives] and the daughters of your paternal uncles and the daughters of your paternal aunts and the daughters of your maternal uncles and the daughters of your maternal aunts who emigrated with you and a believing woman if she gives herself to the Prophet [and] if the Prophet wishes to marry her; [this is] only for you, excluding the [other] believers. We certainly know what We have made obligatory upon them concerning their wives and those their right hands possess, [but this is for you] in order that there will be upon you no discomfort [i.e., difficulty]. And ever is Allāh Forgiving and Merciful.","tr":"Ya ayyuha annabiyyuinna ahlalna laka azwajaka allateeatayta ojoorahunna wama malakat yameenuka mimmaafaa Allahu AAalayka wabanati AAammika wabanatiAAammatika wabanati khalika wabanatikhalatika allatee hajarna maAAaka wamraatanmu/minatan in wahabat nafsaha linnabiyyi in aradaannabiyyu an yastankihaha khalisatanlaka min dooni almu/mineena qad AAalimna ma faradnaAAalayhim fee azwajihim wama malakat aymanuhumlikayla yakoona AAalayka harajun wakana Allahughafooran raheema","juz":22,"page":424},{"s":33,"a":51,"key":"33:51","ar":"۞ تُرْجِى مَن تَشَآءُ مِنْهُنَّ وَتُـْٔوِىٓ إِلَيْكَ مَن تَشَآءُ ۖ وَمَنِ ٱبْتَغَيْتَ مِمَّنْ عَزَلْتَ فَلَا جُنَاحَ عَلَيْكَ ۚ ذَٰلِكَ أَدْنَىٰٓ أَن تَقَرَّ أَعْيُنُهُنَّ وَلَا يَحْزَنَّ وَيَرْضَيْنَ بِمَآ ءَاتَيْتَهُنَّ كُلُّهُنَّ ۚ وَٱللَّهُ يَعْلَمُ مَا فِى قُلُوبِكُمْ ۚ وَكَانَ ٱللَّهُ عَلِيمًا حَلِيمًا","en":"You, [O Muḥammad], may put aside whom you will of them1 or take to yourself whom you will. And any that you desire of those [wives] from whom you had [temporarily] separated - there is no blame upon you [in returning her]. That is more suitable that they should be content and not grieve and that they should be satisfied with what you have given them - all of them. And Allāh knows what is in your hearts. And ever is Allāh Knowing and Forbearing.","tr":"Turjee man tashao minhunna watu/weeilayka man tashao wamani ibtaghayta mimman AAazalta falajunaha AAalayka thalika adna an taqarraaAAyunuhunna wala yahzanna wayardayna bimaataytahunna kulluhunna wallahu yaAAlamu mafee quloobikum wakana Allahu AAaleeman haleema","juz":22,"page":425},{"s":33,"a":52,"key":"33:52","ar":"لَّا يَحِلُّ لَكَ ٱلنِّسَآءُ مِنۢ بَعْدُ وَلَآ أَن تَبَدَّلَ بِهِنَّ مِنْ أَزْوَٰجٍ وَلَوْ أَعْجَبَكَ حُسْنُهُنَّ إِلَّا مَا مَلَكَتْ يَمِينُكَ ۗ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ رَّقِيبًا","en":"Not lawful to you, [O Muḥammad], are [any additional] women after [this], nor [is it] for you to exchange them for [other] wives, even if their beauty were to please you, except what your right hand possesses. And ever is Allāh, over all things, an Observer.1","tr":"La yahillu laka annisaomin baAAdu wala an tabaddala bihinna min azwajinwalaw aAAjabaka husnuhunna illa ma malakatyameenuka wakana Allahu AAala kulli shay-inraqeeba","juz":22,"page":425},{"s":33,"a":53,"key":"33:53","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَدْخُلُوا۟ بُيُوتَ ٱلنَّبِىِّ إِلَّآ أَن يُؤْذَنَ لَكُمْ إِلَىٰ طَعَامٍ غَيْرَ نَـٰظِرِينَ إِنَىٰهُ وَلَـٰكِنْ إِذَا دُعِيتُمْ فَٱدْخُلُوا۟ فَإِذَا طَعِمْتُمْ فَٱنتَشِرُوا۟ وَلَا مُسْتَـْٔنِسِينَ لِحَدِيثٍ ۚ إِنَّ ذَٰلِكُمْ كَانَ يُؤْذِى ٱلنَّبِىَّ فَيَسْتَحْىِۦ مِنكُمْ ۖ وَٱللَّهُ لَا يَسْتَحْىِۦ مِنَ ٱلْحَقِّ ۚ وَإِذَا سَأَلْتُمُوهُنَّ مَتَـٰعًا فَسْـَٔلُوهُنَّ مِن وَرَآءِ حِجَابٍ ۚ ذَٰلِكُمْ أَطْهَرُ لِقُلُوبِكُمْ وَقُلُوبِهِنَّ ۚ وَمَا كَانَ لَكُمْ أَن تُؤْذُوا۟ رَسُولَ ٱللَّهِ وَلَآ أَن تَنكِحُوٓا۟ أَزْوَٰجَهُۥ مِنۢ بَعْدِهِۦٓ أَبَدًا ۚ إِنَّ ذَٰلِكُمْ كَانَ عِندَ ٱللَّهِ عَظِيمًا","en":"O you who have believed, do not enter the houses of the Prophet except when you are permitted for a meal, without awaiting its readiness. But when you are invited, then enter; and when you have eaten, disperse without seeking to remain for conversation. Indeed, that [behavior] was troubling the Prophet, and he is shy of [dismissing] you. But Allāh is not shy of the truth. And when you ask [his wives] for something, ask them from behind a partition. That is purer for your hearts and their hearts. And it is not [conceivable or lawful] for you to harm the Messenger of Allāh or to marry his wives after him, ever. Indeed, that would be in the sight of Allāh an enormity.","tr":"Ya ayyuha allatheena amanoola tadkhuloo buyoota annabiyyi illa an yu/thanalakum ila taAAamin ghayra nathireenainahu walakin itha duAAeetum fadkhuloofa-itha taAAimtum fantashiroo walamusta/niseena lihadeethin inna thalikum kanayu/thee annabiyya fayastahyee minkum wallahula yastahyee mina alhaqqi wa-ithasaaltumoohunna mataAAan fas-aloohunna min wara-ihijabin thalikum atharu liquloobikumwaquloobihinna wama kana lakum an tu/thoorasoola Allahi wala an tankihoo azwajahumin baAAdihi abadan inna thalikum kana AAinda AllahiAAatheema","juz":22,"page":425},{"s":33,"a":54,"key":"33:54","ar":"إِن تُبْدُوا۟ شَيْـًٔا أَوْ تُخْفُوهُ فَإِنَّ ٱللَّهَ كَانَ بِكُلِّ شَىْءٍ عَلِيمًا","en":"Whether you reveal a thing or conceal it, indeed Allāh is ever, of all things, Knowing.","tr":"In tubdoo shay-an aw tukhfoohu fa-inna Allahakana bikulli shay-in AAaleema","juz":22,"page":425},{"s":33,"a":55,"key":"33:55","ar":"لَّا جُنَاحَ عَلَيْهِنَّ فِىٓ ءَابَآئِهِنَّ وَلَآ أَبْنَآئِهِنَّ وَلَآ إِخْوَٰنِهِنَّ وَلَآ أَبْنَآءِ إِخْوَٰنِهِنَّ وَلَآ أَبْنَآءِ أَخَوَٰتِهِنَّ وَلَا نِسَآئِهِنَّ وَلَا مَا مَلَكَتْ أَيْمَـٰنُهُنَّ ۗ وَٱتَّقِينَ ٱللَّهَ ۚ إِنَّ ٱللَّهَ كَانَ عَلَىٰ كُلِّ شَىْءٍ شَهِيدًا","en":"There is no blame upon them [i.e., women] concerning their fathers or their sons or their brothers or their brothers' sons or their sisters' sons or their women or those their right hands possess [i.e., slaves].1 And fear Allāh. Indeed Allāh is ever, over all things, Witness.","tr":"La junaha AAalayhinna fee aba-ihinnawala abna-ihinna wala ikhwanihinnawala abna-i ikhwanihinna wala abna-iakhawatihinna wala nisa-ihinna wala mamalakat aymanuhunna wattaqeena Allaha innaAllaha kana AAala kulli shay-in shaheeda","juz":22,"page":426},{"s":33,"a":56,"key":"33:56","ar":"إِنَّ ٱللَّهَ وَمَلَـٰٓئِكَتَهُۥ يُصَلُّونَ عَلَى ٱلنَّبِىِّ ۚ يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ صَلُّوا۟ عَلَيْهِ وَسَلِّمُوا۟ تَسْلِيمًا","en":"Indeed, Allāh confers blessing upon the Prophet, and His angels [ask Him to do so]. O you who have believed, ask [Allāh to confer] blessing upon him and ask [Allāh to grant him] peace.","tr":"Inna Allaha wamala-ikatahu yusalloonaAAala annabiyyi ya ayyuha allatheenaamanoo salloo AAalayhi wasallimoo tasleema","juz":22,"page":426},{"s":33,"a":57,"key":"33:57","ar":"إِنَّ ٱلَّذِينَ يُؤْذُونَ ٱللَّهَ وَرَسُولَهُۥ لَعَنَهُمُ ٱللَّهُ فِى ٱلدُّنْيَا وَٱلْـَٔاخِرَةِ وَأَعَدَّ لَهُمْ عَذَابًا مُّهِينًا","en":"Indeed, those who abuse Allāh and His Messenger - Allāh has cursed them in this world and the Hereafter and prepared for them a humiliating punishment.","tr":"Inna allatheena yu/thoona Allahawarasoolahu laAAanahumu Allahu fee addunyawal-akhirati waaAAadda lahum AAathabanmuheena","juz":22,"page":426},{"s":33,"a":58,"key":"33:58","ar":"وَٱلَّذِينَ يُؤْذُونَ ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَـٰتِ بِغَيْرِ مَا ٱكْتَسَبُوا۟ فَقَدِ ٱحْتَمَلُوا۟ بُهْتَـٰنًا وَإِثْمًا مُّبِينًا","en":"And those who harm believing men and believing women for [something] other than what they have earned [i.e., deserved] have certainly borne upon themselves a slander and manifest sin.","tr":"Wallatheena yu/thoonaalmu/mineena walmu/minati bighayri maiktasaboo faqadi ihtamaloo buhtanan wa-ithmanmubeena","juz":22,"page":426},{"s":33,"a":59,"key":"33:59","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ قُل لِّأَزْوَٰجِكَ وَبَنَاتِكَ وَنِسَآءِ ٱلْمُؤْمِنِينَ يُدْنِينَ عَلَيْهِنَّ مِن جَلَـٰبِيبِهِنَّ ۚ ذَٰلِكَ أَدْنَىٰٓ أَن يُعْرَفْنَ فَلَا يُؤْذَيْنَ ۗ وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًا","en":"O Prophet, tell your wives and your daughters and the women of the believers to bring down over themselves [part] of their outer garments.1 That is more suitable that they will be known2 and not be abused. And ever is Allāh Forgiving and Merciful.3","tr":"Ya ayyuha annabiyyuqul li-azwajika wabanatika wanisa-ialmu/mineena yudneena AAalayhinna min jalabeebihinna thalikaadna an yuAArafna fala yu/thayna wakanaAllahu ghafooran raheema","juz":22,"page":426},{"s":33,"a":60,"key":"33:60","ar":"۞ لَّئِن لَّمْ يَنتَهِ ٱلْمُنَـٰفِقُونَ وَٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌ وَٱلْمُرْجِفُونَ فِى ٱلْمَدِينَةِ لَنُغْرِيَنَّكَ بِهِمْ ثُمَّ لَا يُجَاوِرُونَكَ فِيهَآ إِلَّا قَلِيلًا","en":"If the hypocrites and those in whose hearts is disease1 and those who spread rumors in al-Madīnah do not cease, We will surely incite you against them; then they will not remain your neighbors therein except for a little,","tr":"La-in lam yantahi almunafiqoona wallatheenafee quloobihim maradun walmurjifoona feealmadeenati lanughriyannaka bihim thumma la yujawiroonakafeeha illa qaleela","juz":22,"page":426},{"s":33,"a":61,"key":"33:61","ar":"مَّلْعُونِينَ ۖ أَيْنَمَا ثُقِفُوٓا۟ أُخِذُوا۟ وَقُتِّلُوا۟ تَقْتِيلًا","en":"Accursed wherever they are found, [being] seized and massacred completely.","tr":"MalAAooneena ayna ma thuqifoo okhithoowaquttiloo taqteela","juz":22,"page":426},{"s":33,"a":62,"key":"33:62","ar":"سُنَّةَ ٱللَّهِ فِى ٱلَّذِينَ خَلَوْا۟ مِن قَبْلُ ۖ وَلَن تَجِدَ لِسُنَّةِ ٱللَّهِ تَبْدِيلًا","en":"[This is] the established way of Allāh with those who passed on before; and you will not find in the way of Allāh any change.","tr":"Sunnata Allahi fee allatheenakhalaw min qablu walan tajida lisunnati Allahi tabdeela","juz":22,"page":426},{"s":33,"a":63,"key":"33:63","ar":"يَسْـَٔلُكَ ٱلنَّاسُ عَنِ ٱلسَّاعَةِ ۖ قُلْ إِنَّمَا عِلْمُهَا عِندَ ٱللَّهِ ۚ وَمَا يُدْرِيكَ لَعَلَّ ٱلسَّاعَةَ تَكُونُ قَرِيبًا","en":"People ask you concerning the Hour. Say, \"Knowledge of it is only with Allāh. And what may make you perceive? Perhaps the Hour is near.\"","tr":"Yas-aluka annasu AAani assaAAatiqul innama AAilmuha AAinda Allahi wamayudreeka laAAalla assaAAata takoonu qareeba","juz":22,"page":427},{"s":33,"a":64,"key":"33:64","ar":"إِنَّ ٱللَّهَ لَعَنَ ٱلْكَـٰفِرِينَ وَأَعَدَّ لَهُمْ سَعِيرًا","en":"Indeed, Allāh has cursed the disbelievers and prepared for them a Blaze.","tr":"Inna Allaha laAAana alkafireenawaaAAadda lahum saAAeera","juz":22,"page":427},{"s":33,"a":65,"key":"33:65","ar":"خَـٰلِدِينَ فِيهَآ أَبَدًا ۖ لَّا يَجِدُونَ وَلِيًّا وَلَا نَصِيرًا","en":"Abiding therein forever, they will not find a protector or a helper.","tr":"Khalideena feeha abadan layajidoona waliyyan wala naseera","juz":22,"page":427},{"s":33,"a":66,"key":"33:66","ar":"يَوْمَ تُقَلَّبُ وُجُوهُهُمْ فِى ٱلنَّارِ يَقُولُونَ يَـٰلَيْتَنَآ أَطَعْنَا ٱللَّهَ وَأَطَعْنَا ٱلرَّسُولَا۠","en":"The Day their faces will be turned about in the Fire, they will say, \"How we wish we had obeyed Allāh and obeyed the Messenger.\"","tr":"Yawma tuqallabu wujoohuhum fee annariyaqooloona ya laytana ataAAna AllahawaataAAna arrasoola","juz":22,"page":427},{"s":33,"a":67,"key":"33:67","ar":"وَقَالُوا۟ رَبَّنَآ إِنَّآ أَطَعْنَا سَادَتَنَا وَكُبَرَآءَنَا فَأَضَلُّونَا ٱلسَّبِيلَا۠","en":"And they will say, \"Our Lord, indeed we obeyed our masters and our dignitaries,1 and they led us astray from the [right] way.","tr":"Waqaloo rabbana inna ataAAnasadatana wakubaraana faadalloonaassabeela","juz":22,"page":427},{"s":33,"a":68,"key":"33:68","ar":"رَبَّنَآ ءَاتِهِمْ ضِعْفَيْنِ مِنَ ٱلْعَذَابِ وَٱلْعَنْهُمْ لَعْنًا كَبِيرًا","en":"Our Lord, give them double the punishment and curse them with a great curse.\"","tr":"Rabbana atihim diAAfaynimina alAAathabi walAAanhum laAAnan kabeera","juz":22,"page":427},{"s":33,"a":69,"key":"33:69","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَكُونُوا۟ كَٱلَّذِينَ ءَاذَوْا۟ مُوسَىٰ فَبَرَّأَهُ ٱللَّهُ مِمَّا قَالُوا۟ ۚ وَكَانَ عِندَ ٱللَّهِ وَجِيهًا","en":"O you who have believed, be not like those who abused Moses; then Allāh cleared him of what they said. And he, in the sight of Allāh, was distinguished.","tr":"Ya ayyuha allatheena amanoola takoonoo kallatheena athaw moosafabarraahu Allahu mimma qaloo wakanaAAinda Allahi wajeeha","juz":22,"page":427},{"s":33,"a":70,"key":"33:70","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَقُولُوا۟ قَوْلًا سَدِيدًا","en":"O you who have believed, fear Allāh and speak words of appropriate justice.","tr":"Ya ayyuha allatheena amanooittaqoo Allaha waqooloo qawlan sadeeda","juz":22,"page":427},{"s":33,"a":71,"key":"33:71","ar":"يُصْلِحْ لَكُمْ أَعْمَـٰلَكُمْ وَيَغْفِرْ لَكُمْ ذُنُوبَكُمْ ۗ وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ فَقَدْ فَازَ فَوْزًا عَظِيمًا","en":"He will [then] amend for you your deeds and forgive you your sins. And whoever obeys Allāh and His Messenger has certainly attained a great attainment.","tr":"Yuslih lakum aAAmalakumwayaghfir lakum thunoobakum waman yutiAAi Allahawarasoolahu faqad faza fawzan AAatheema","juz":22,"page":427},{"s":33,"a":72,"key":"33:72","ar":"إِنَّا عَرَضْنَا ٱلْأَمَانَةَ عَلَى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَٱلْجِبَالِ فَأَبَيْنَ أَن يَحْمِلْنَهَا وَأَشْفَقْنَ مِنْهَا وَحَمَلَهَا ٱلْإِنسَـٰنُ ۖ إِنَّهُۥ كَانَ ظَلُومًا جَهُولًا","en":"Indeed, We offered the Trust1 to the heavens and the earth and the mountains, and they declined to bear it and feared it; but man [undertook to] bear it. Indeed, he was unjust and ignorant.2","tr":"Inna AAaradna al-amanataAAala assamawati wal-ardiwaljibali faabayna an yahmilnahawaashfaqna minha wahamalaha al-insanuinnahu kana thalooman jahoola","juz":22,"page":427},{"s":33,"a":73,"key":"33:73","ar":"لِّيُعَذِّبَ ٱللَّهُ ٱلْمُنَـٰفِقِينَ وَٱلْمُنَـٰفِقَـٰتِ وَٱلْمُشْرِكِينَ وَٱلْمُشْرِكَـٰتِ وَيَتُوبَ ٱللَّهُ عَلَى ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَـٰتِ ۗ وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًۢا","en":"[It1 was] so that Allāh may punish the hypocrite men and hypocrite women and the men and women who associate others with Him and that Allāh may accept repentance from the believing men and believing women. And ever is Allāh Forgiving and Merciful.","tr":"LiyuAAaththiba Allahu almunafiqeenawalmunafiqati walmushrikeena walmushrikatiwayatooba Allahu AAala almu/mineena walmu/minatiwakana Allahu ghafooran raheema","juz":22,"page":427},{"s":34,"a":1,"key":"34:1","ar":" ٱلْحَمْدُ لِلَّهِ ٱلَّذِى لَهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ وَلَهُ ٱلْحَمْدُ فِى ٱلْـَٔاخِرَةِ ۚ وَهُوَ ٱلْحَكِيمُ ٱلْخَبِيرُ","en":"[All] praise is [due] to Allāh, to whom belongs whatever is in the heavens and whatever is in the earth, and to Him belongs [all] praise in the Hereafter. And He is the Wise, the Aware.","tr":"Alhamdu lillahi allatheelahu ma fee assamawati wamafee al-ardi walahu alhamdu fee al-akhiratiwahuwa alhakeemu alkhabeer","juz":22,"page":428},{"s":34,"a":2,"key":"34:2","ar":"يَعْلَمُ مَا يَلِجُ فِى ٱلْأَرْضِ وَمَا يَخْرُجُ مِنْهَا وَمَا يَنزِلُ مِنَ ٱلسَّمَآءِ وَمَا يَعْرُجُ فِيهَا ۚ وَهُوَ ٱلرَّحِيمُ ٱلْغَفُورُ","en":"He knows what penetrates into the earth and what emerges from it and what descends from the heaven and what ascends therein. And He is the Merciful, the Forgiving.","tr":"YaAAlamu ma yaliju fee al-ardiwama yakhruju minha wama yanzilu mina assama-iwama yaAAruju feeha wahuwa arraheemualghafoor","juz":22,"page":428},{"s":34,"a":3,"key":"34:3","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَا تَأْتِينَا ٱلسَّاعَةُ ۖ قُلْ بَلَىٰ وَرَبِّى لَتَأْتِيَنَّكُمْ عَـٰلِمِ ٱلْغَيْبِ ۖ لَا يَعْزُبُ عَنْهُ مِثْقَالُ ذَرَّةٍ فِى ٱلسَّمَـٰوَٰتِ وَلَا فِى ٱلْأَرْضِ وَلَآ أَصْغَرُ مِن ذَٰلِكَ وَلَآ أَكْبَرُ إِلَّا فِى كِتَـٰبٍ مُّبِينٍ","en":"But those who disbelieve say, \"The Hour will not come to us.\" Say, \"Yes, by my Lord, it will surely come to you. [Allāh is] the Knower of the unseen.\" Not absent from Him is an atom's weight1 within the heavens or within the earth or [what is] smaller than that or greater, except that it is in a clear register -","tr":"Waqala allatheena kafaroo lata/teena assaAAatu qul bala warabbeelata/tiyannakum AAalimi alghaybi la yaAAzubu AAanhumithqalu tharratin fee assamawatiwala fee al-ardi wala asgharu min thalikawala akbaru illa fee kitabin mubeen","juz":22,"page":428},{"s":34,"a":4,"key":"34:4","ar":"لِّيَجْزِىَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ ۚ أُو۟لَـٰٓئِكَ لَهُم مَّغْفِرَةٌ وَرِزْقٌ كَرِيمٌ","en":"That He may reward those who believe and do righteous deeds. Those will have forgiveness and noble provision.","tr":"Liyajziya allatheena amanoowaAAamiloo assalihati ola-ika lahummaghfiratun warizqun kareem","juz":22,"page":428},{"s":34,"a":5,"key":"34:5","ar":"وَٱلَّذِينَ سَعَوْ فِىٓ ءَايَـٰتِنَا مُعَـٰجِزِينَ أُو۟لَـٰٓئِكَ لَهُمْ عَذَابٌ مِّن رِّجْزٍ أَلِيمٌ","en":"But those who strive against Our verses [seeking] to cause failure1 - for them will be a painful punishment of foul nature.","tr":"Wallatheena saAAaw fee ayatinamuAAajizeena ola-ika lahum AAathabun minrijzin aleem","juz":22,"page":428},{"s":34,"a":6,"key":"34:6","ar":"وَيَرَى ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ ٱلَّذِىٓ أُنزِلَ إِلَيْكَ مِن رَّبِّكَ هُوَ ٱلْحَقَّ وَيَهْدِىٓ إِلَىٰ صِرَٰطِ ٱلْعَزِيزِ ٱلْحَمِيدِ","en":"And those who have been given knowledge see that what is revealed to you from your Lord is the truth, and it guides to the path of the Exalted in Might, the Praiseworthy.","tr":"Wayara allatheena ootooalAAilma allathee onzila ilayka min rabbika huwa alhaqqawayahdee ila sirati alAAazeezi alhameed","juz":22,"page":428},{"s":34,"a":7,"key":"34:7","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوا۟ هَلْ نَدُلُّكُمْ عَلَىٰ رَجُلٍ يُنَبِّئُكُمْ إِذَا مُزِّقْتُمْ كُلَّ مُمَزَّقٍ إِنَّكُمْ لَفِى خَلْقٍ جَدِيدٍ","en":"But those who disbelieve say, \"Shall we direct you to a man who will inform you [that] when you have disintegrated in complete disintegration, you will [then] be [recreated] in a new creation?","tr":"Waqala allatheena kafaroo halnadullukum AAala rajulin yunabbi-okum ithamuzziqtum kulla mumazzaqin innakum lafee khalqin jadeed","juz":22,"page":428},{"s":34,"a":8,"key":"34:8","ar":"أَفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَم بِهِۦ جِنَّةٌۢ ۗ بَلِ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ فِى ٱلْعَذَابِ وَٱلضَّلَـٰلِ ٱلْبَعِيدِ","en":"Has he invented about Allāh a lie or is there in him madness?\" Rather, they who do not believe in the Hereafter will be in the punishment and [are in] extreme error.","tr":"Aftara AAala Allahi kathibanam bihi jinnatun bali allatheena la yu/minoona bil-akhiratifee alAAathabi waddalali albaAAeed","juz":22,"page":429},{"s":34,"a":9,"key":"34:9","ar":"أَفَلَمْ يَرَوْا۟ إِلَىٰ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُم مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ ۚ إِن نَّشَأْ نَخْسِفْ بِهِمُ ٱلْأَرْضَ أَوْ نُسْقِطْ عَلَيْهِمْ كِسَفًا مِّنَ ٱلسَّمَآءِ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَةً لِّكُلِّ عَبْدٍ مُّنِيبٍ","en":"Then, do they not look at what is before them and what is behind them of the heaven and earth? If We should will, We could cause the earth to swallow them or [could] let fall upon them fragments from the sky. Indeed in that is a sign for every servant turning back [to Allāh].","tr":"Afalam yaraw ila ma baynaaydeehim wama khalfahum mina assama-i wal-ardiin nasha/ nakhsif bihimu al-arda aw nusqitAAalayhim kisafan mina assama-i inna fee thalikalaayatan likulli AAabdin muneeb","juz":22,"page":429},{"s":34,"a":10,"key":"34:10","ar":"۞ وَلَقَدْ ءَاتَيْنَا دَاوُۥدَ مِنَّا فَضْلًا ۖ يَـٰجِبَالُ أَوِّبِى مَعَهُۥ وَٱلطَّيْرَ ۖ وَأَلَنَّا لَهُ ٱلْحَدِيدَ","en":"And We certainly gave David from Us bounty. [We said], \"O mountains, repeat [Our] praises with him, and the birds [as well].\" And We made pliable for him iron,","tr":"Walaqad atayna dawoodaminna fadlan ya jibalu awwibeemaAAahu wattayra waalanna lahu alhadeed","juz":22,"page":429},{"s":34,"a":11,"key":"34:11","ar":"أَنِ ٱعْمَلْ سَـٰبِغَـٰتٍ وَقَدِّرْ فِى ٱلسَّرْدِ ۖ وَٱعْمَلُوا۟ صَـٰلِحًا ۖ إِنِّى بِمَا تَعْمَلُونَ بَصِيرٌ","en":"[Commanding him], \"Make full coats of mail and calculate [precisely] the links, and work [all of you] righteousness. Indeed I, of what you do, am Seeing.\"","tr":"Ani iAAmal sabighatin waqaddirfee assardi waAAmaloo salihan inneebima taAAmaloona baseer","juz":22,"page":429},{"s":34,"a":12,"key":"34:12","ar":"وَلِسُلَيْمَـٰنَ ٱلرِّيحَ غُدُوُّهَا شَهْرٌ وَرَوَاحُهَا شَهْرٌ ۖ وَأَسَلْنَا لَهُۥ عَيْنَ ٱلْقِطْرِ ۖ وَمِنَ ٱلْجِنِّ مَن يَعْمَلُ بَيْنَ يَدَيْهِ بِإِذْنِ رَبِّهِۦ ۖ وَمَن يَزِغْ مِنْهُمْ عَنْ أَمْرِنَا نُذِقْهُ مِنْ عَذَابِ ٱلسَّعِيرِ","en":"And to Solomon [We subjected] the wind - its morning [journey was that of] a month - and its afternoon [journey was that of] a month, and We made flow for him a spring of [liquid] copper. And among the jinn were those who worked for him by the permission of his Lord. And whoever deviated among them from Our command - We will make him taste of the punishment of the Blaze.","tr":"Walisulaymana arreehaghuduwwuha shahrun warawahuha shahrunwaasalna lahu AAayna alqitri wamina aljinni manyaAAmalu bayna yadayhi bi-ithni rabbihi waman yazighminhum AAan amrina nuthiqhu min AAathabi assaAAeer","juz":22,"page":429},{"s":34,"a":13,"key":"34:13","ar":"يَعْمَلُونَ لَهُۥ مَا يَشَآءُ مِن مَّحَـٰرِيبَ وَتَمَـٰثِيلَ وَجِفَانٍ كَٱلْجَوَابِ وَقُدُورٍ رَّاسِيَـٰتٍ ۚ ٱعْمَلُوٓا۟ ءَالَ دَاوُۥدَ شُكْرًا ۚ وَقَلِيلٌ مِّنْ عِبَادِىَ ٱلشَّكُورُ","en":"They made for him what he willed of elevated chambers,1 statues,2 bowls like reservoirs, and stationary kettles. [We said], \"Work, O family of David, in gratitude.\" And few of My servants are grateful.","tr":"YaAAmaloona lahu ma yashao minmahareeba watamatheela wajifanin kaljawabiwaqudoorin rasiyatin iAAmaloo ala dawoodashukran waqaleelun min AAibadiya ashshakoor","juz":22,"page":429},{"s":34,"a":14,"key":"34:14","ar":"فَلَمَّا قَضَيْنَا عَلَيْهِ ٱلْمَوْتَ مَا دَلَّهُمْ عَلَىٰ مَوْتِهِۦٓ إِلَّا دَآبَّةُ ٱلْأَرْضِ تَأْكُلُ مِنسَأَتَهُۥ ۖ فَلَمَّا خَرَّ تَبَيَّنَتِ ٱلْجِنُّ أَن لَّوْ كَانُوا۟ يَعْلَمُونَ ٱلْغَيْبَ مَا لَبِثُوا۟ فِى ٱلْعَذَابِ ٱلْمُهِينِ","en":"And when We decreed for him [i.e., Solomon] death, nothing indicated to them [i.e., the jinn] his death except a creature of the earth eating his staff.1 But when he fell, it became clear to the jinn that if they had known the unseen, they would not have remained in humiliating punishment.2","tr":"Falamma qadaynaAAalayhi almawta ma dallahum AAala mawtihi illadabbatu al-ardi ta/kulu minsaatahu falammakharra tabayyanati aljinnu an law kanoo yaAAlamoonaalghayba ma labithoo fee alAAathabi almuheen","juz":22,"page":429},{"s":34,"a":15,"key":"34:15","ar":"لَقَدْ كَانَ لِسَبَإٍ فِى مَسْكَنِهِمْ ءَايَةٌ ۖ جَنَّتَانِ عَن يَمِينٍ وَشِمَالٍ ۖ كُلُوا۟ مِن رِّزْقِ رَبِّكُمْ وَٱشْكُرُوا۟ لَهُۥ ۚ بَلْدَةٌ طَيِّبَةٌ وَرَبٌّ غَفُورٌ","en":"There was for [the tribe of] Saba’ in their dwelling place a sign: two [fields of] gardens on the right and on the left. [They were told], \"Eat from the provisions of your Lord and be grateful to Him. A good land [have you], and a forgiving Lord.\"","tr":"Laqad kana lisaba-in fee maskanihim ayatunjannatani AAan yameenin washimalin kuloo min rizqirabbikum washkuroo lahu baldatun tayyibatunwarabbun ghafoor","juz":22,"page":430},{"s":34,"a":16,"key":"34:16","ar":"فَأَعْرَضُوا۟ فَأَرْسَلْنَا عَلَيْهِمْ سَيْلَ ٱلْعَرِمِ وَبَدَّلْنَـٰهُم بِجَنَّتَيْهِمْ جَنَّتَيْنِ ذَوَاتَىْ أُكُلٍ خَمْطٍ وَأَثْلٍ وَشَىْءٍ مِّن سِدْرٍ قَلِيلٍ","en":"But they turned away [refusing], so We sent upon them the flood of the dam,1 and We replaced their two [fields of] gardens with gardens of bitter fruit, tamarisks and something of sparse lote trees.","tr":"FaaAAradoo faarsalna AAalayhimsayla alAAarimi wabaddalnahum bijannatayhim jannatayni thawatayokulin khamtin waathlin washay-in min sidrin qaleel","juz":22,"page":430},{"s":34,"a":17,"key":"34:17","ar":"ذَٰلِكَ جَزَيْنَـٰهُم بِمَا كَفَرُوا۟ ۖ وَهَلْ نُجَـٰزِىٓ إِلَّا ٱلْكَفُورَ","en":"[By] that We repaid them because they disbelieved. And do We [thus] repay except the ungrateful?","tr":"Thalika jazaynahum bimakafaroo wahal nujazee illa alkafoor","juz":22,"page":430},{"s":34,"a":18,"key":"34:18","ar":"وَجَعَلْنَا بَيْنَهُمْ وَبَيْنَ ٱلْقُرَى ٱلَّتِى بَـٰرَكْنَا فِيهَا قُرًى ظَـٰهِرَةً وَقَدَّرْنَا فِيهَا ٱلسَّيْرَ ۖ سِيرُوا۟ فِيهَا لَيَالِىَ وَأَيَّامًا ءَامِنِينَ","en":"And We placed between them and the cities which We had blessed1 [many] visible cities. And We determined between them the [distances of] journey,2 [saying], \"Travel between them by night or by day in safety.\"","tr":"WajaAAalna baynahum wabayna alquraallatee barakna feeha quran thahiratanwaqaddarna feeha assayra seeroo feehalayaliya waayyaman amineen","juz":22,"page":430},{"s":34,"a":19,"key":"34:19","ar":"فَقَالُوا۟ رَبَّنَا بَـٰعِدْ بَيْنَ أَسْفَارِنَا وَظَلَمُوٓا۟ أَنفُسَهُمْ فَجَعَلْنَـٰهُمْ أَحَادِيثَ وَمَزَّقْنَـٰهُمْ كُلَّ مُمَزَّقٍ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّكُلِّ صَبَّارٍ شَكُورٍ","en":"But [insolently] they said, \"Our Lord, lengthen the distance between our journeys,\" and wronged themselves, so We made them narrations1 and dispersed them in total dispersion. Indeed in that are signs for everyone patient and grateful.","tr":"Faqaloo rabbana baAAidbayna asfarina wathalamoo anfusahumfajaAAalnahum ahadeetha wamazzaqnahum kullamumazzaqin inna fee thalika laayatin likullisabbarin shakoor","juz":22,"page":430},{"s":34,"a":20,"key":"34:20","ar":"وَلَقَدْ صَدَّقَ عَلَيْهِمْ إِبْلِيسُ ظَنَّهُۥ فَٱتَّبَعُوهُ إِلَّا فَرِيقًا مِّنَ ٱلْمُؤْمِنِينَ","en":"And Iblees had already confirmed through them1 his assumption,2 so they followed him, except for a party of believers.","tr":"Walaqad saddaqa AAalayhim ibleesu thannahufattabaAAoohu illa fareeqan mina almu/mineen","juz":22,"page":430},{"s":34,"a":21,"key":"34:21","ar":"وَمَا كَانَ لَهُۥ عَلَيْهِم مِّن سُلْطَـٰنٍ إِلَّا لِنَعْلَمَ مَن يُؤْمِنُ بِٱلْـَٔاخِرَةِ مِمَّنْ هُوَ مِنْهَا فِى شَكٍّ ۗ وَرَبُّكَ عَلَىٰ كُلِّ شَىْءٍ حَفِيظٌ","en":"And he had over them no authority except [it was decreed] that We might make evident who believes in the Hereafter from who is thereof in doubt. And your Lord, over all things, is Guardian.1","tr":"Wama kana lahu AAalayhim minsultanin illa linaAAlama man yu/minu bil-akhiratimimman huwa minha fee shakkin warabbuka AAala kullishay-in hafeeth","juz":22,"page":430},{"s":34,"a":22,"key":"34:22","ar":"قُلِ ٱدْعُوا۟ ٱلَّذِينَ زَعَمْتُم مِّن دُونِ ٱللَّهِ ۖ لَا يَمْلِكُونَ مِثْقَالَ ذَرَّةٍ فِى ٱلسَّمَـٰوَٰتِ وَلَا فِى ٱلْأَرْضِ وَمَا لَهُمْ فِيهِمَا مِن شِرْكٍ وَمَا لَهُۥ مِنْهُم مِّن ظَهِيرٍ","en":"Say, [O Muḥammad], \"Invoke those you claim [as deities] besides Allāh.\" They do not possess an atom's weight [of ability] in the heavens or on the earth, and they do not have therein any partnership [with Him], nor is there for Him from among them any assistant.","tr":"Quli odAAoo allatheena zaAAamtum mindooni Allahi la yamlikoona mithqala tharratinfee assamawati wala fee al-ardiwama lahum feehima min shirkin wama lahuminhum min thaheer","juz":22,"page":430},{"s":34,"a":23,"key":"34:23","ar":"وَلَا تَنفَعُ ٱلشَّفَـٰعَةُ عِندَهُۥٓ إِلَّا لِمَنْ أَذِنَ لَهُۥ ۚ حَتَّىٰٓ إِذَا فُزِّعَ عَن قُلُوبِهِمْ قَالُوا۟ مَاذَا قَالَ رَبُّكُمْ ۖ قَالُوا۟ ٱلْحَقَّ ۖ وَهُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ","en":"And intercession does not benefit with Him except for one whom He permits. [And those wait] until, when terror is removed from their hearts,1 they will say [to one another], \"What has your Lord said?\" They will say, \"The truth.\" And He is the Most High, the Grand.","tr":"Wala tanfaAAu ashshafaAAatuAAindahu illa liman athina lahu hattaitha fuzziAAa AAan quloobihim qaloo matha qalarabbukum qaloo alhaqqa wahuwa alAAaliyyu alkabeer","juz":22,"page":431},{"s":34,"a":24,"key":"34:24","ar":"۞ قُلْ مَن يَرْزُقُكُم مِّنَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ قُلِ ٱللَّهُ ۖ وَإِنَّآ أَوْ إِيَّاكُمْ لَعَلَىٰ هُدًى أَوْ فِى ضَلَـٰلٍ مُّبِينٍ","en":"Say, \"Who provides for you from the heavens and the earth?\" Say, \"Allāh. And indeed, we or you are either upon guidance or in clear error.\"","tr":"Qul man yarzuqukum mina assamawatiwal-ardi quli Allahu wa-inna aw iyyakumlaAAala hudan aw fee dalalin mubeen","juz":22,"page":431},{"s":34,"a":25,"key":"34:25","ar":"قُل لَّا تُسْـَٔلُونَ عَمَّآ أَجْرَمْنَا وَلَا نُسْـَٔلُ عَمَّا تَعْمَلُونَ","en":"Say, \"You will not be asked about what we committed, and we will not be asked about what you do.\"","tr":"Qul la tus-aloona AAammaajramna wala nus-alu AAamma taAAmaloon","juz":22,"page":431},{"s":34,"a":26,"key":"34:26","ar":"قُلْ يَجْمَعُ بَيْنَنَا رَبُّنَا ثُمَّ يَفْتَحُ بَيْنَنَا بِٱلْحَقِّ وَهُوَ ٱلْفَتَّاحُ ٱلْعَلِيمُ","en":"Say, \"Our Lord will bring us together; then He will judge between us in truth. And He is the Knowing Judge.\"1","tr":"Qul yajmaAAu baynana rabbunathumma yaftahu baynana bilhaqqiwahuwa alfattahu alAAaleem","juz":22,"page":431},{"s":34,"a":27,"key":"34:27","ar":"قُلْ أَرُونِىَ ٱلَّذِينَ أَلْحَقْتُم بِهِۦ شُرَكَآءَ ۖ كَلَّا ۚ بَلْ هُوَ ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Say, \"Show me those whom you have attached to Him as partners. No! Rather, He [alone] is Allāh, the Exalted in Might, the Wise.\"","tr":"Qul arooniya allatheena alhaqtumbihi shurakaa kalla bal huwa AllahualAAazeezu alhakeem","juz":22,"page":431},{"s":34,"a":28,"key":"34:28","ar":"وَمَآ أَرْسَلْنَـٰكَ إِلَّا كَآفَّةً لِّلنَّاسِ بَشِيرًا وَنَذِيرًا وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"And We have not sent you except comprehensively1 to mankind as a bringer of good tidings and a warner. But most of the people do not know.","tr":"Wama arsalnaka illa kaffatanlinnasi basheeran wanatheeran walakinnaakthara annasi la yaAAlamoon","juz":22,"page":431},{"s":34,"a":29,"key":"34:29","ar":"وَيَقُولُونَ مَتَىٰ هَـٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَ","en":"And they say, \"When is this promise, if you should be truthful?\"","tr":"Wayaqooloona mata hathaalwaAAdu in kuntum sadiqeen","juz":22,"page":431},{"s":34,"a":30,"key":"34:30","ar":"قُل لَّكُم مِّيعَادُ يَوْمٍ لَّا تَسْتَـْٔخِرُونَ عَنْهُ سَاعَةً وَلَا تَسْتَقْدِمُونَ","en":"Say, \"For you is the appointment of a Day [when] you will not remain thereafter an hour, nor will you precede [it].\"","tr":"Qul lakum meeAAadu yawmin latasta/khiroona AAanhu saAAatan wala tastaqdimoon","juz":22,"page":431},{"s":34,"a":31,"key":"34:31","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَن نُّؤْمِنَ بِهَـٰذَا ٱلْقُرْءَانِ وَلَا بِٱلَّذِى بَيْنَ يَدَيْهِ ۗ وَلَوْ تَرَىٰٓ إِذِ ٱلظَّـٰلِمُونَ مَوْقُوفُونَ عِندَ رَبِّهِمْ يَرْجِعُ بَعْضُهُمْ إِلَىٰ بَعْضٍ ٱلْقَوْلَ يَقُولُ ٱلَّذِينَ ٱسْتُضْعِفُوا۟ لِلَّذِينَ ٱسْتَكْبَرُوا۟ لَوْلَآ أَنتُمْ لَكُنَّا مُؤْمِنِينَ","en":"And those who disbelieve say, \"We will never believe in this Qur’ān nor in that before it.\" But if you could see when the wrongdoers are made to stand before their Lord, refuting each others' words...1 Those who were oppressed will say to those who were arrogant, \"If not for you, we would have been believers.\"","tr":"Waqala allatheena kafaroo lannu/mina bihatha alqur-ani wala billatheebayna yadayhi walaw tara ithi aththalimoonamawqoofoona AAinda rabbihim yarjiAAu baAAduhum ilabaAAdin alqawla yaqoolu allatheena istudAAifoolillatheena istakbaroo lawla antum lakunnamu/mineen","juz":22,"page":431},{"s":34,"a":32,"key":"34:32","ar":"قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ لِلَّذِينَ ٱسْتُضْعِفُوٓا۟ أَنَحْنُ صَدَدْنَـٰكُمْ عَنِ ٱلْهُدَىٰ بَعْدَ إِذْ جَآءَكُم ۖ بَلْ كُنتُم مُّجْرِمِينَ","en":"Those who were arrogant will say to those who were oppressed, \"Did we avert you from guidance after it had come to you? Rather, you were criminals.\"","tr":"Qala allatheena istakbaroolillatheena istudAAifoo anahnu sadadnakumAAani alhuda baAAda ith jaakum bal kuntummujrimeen","juz":22,"page":432},{"s":34,"a":33,"key":"34:33","ar":"وَقَالَ ٱلَّذِينَ ٱسْتُضْعِفُوا۟ لِلَّذِينَ ٱسْتَكْبَرُوا۟ بَلْ مَكْرُ ٱلَّيْلِ وَٱلنَّهَارِ إِذْ تَأْمُرُونَنَآ أَن نَّكْفُرَ بِٱللَّهِ وَنَجْعَلَ لَهُۥٓ أَندَادًا ۚ وَأَسَرُّوا۟ ٱلنَّدَامَةَ لَمَّا رَأَوُا۟ ٱلْعَذَابَ وَجَعَلْنَا ٱلْأَغْلَـٰلَ فِىٓ أَعْنَاقِ ٱلَّذِينَ كَفَرُوا۟ ۚ هَلْ يُجْزَوْنَ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ","en":"Those who were oppressed will say to those who were arrogant, \"Rather, [it was your] conspiracy of night and day when you were ordering us to disbelieve in Allāh and attribute to Him equals.\" But they will [all] confide regret when they see the punishment; and We will put shackles on the necks of those who disbelieved. Will they be recompensed except for what they used to do?","tr":"Waqala allatheena istudAAifoolillatheena istakbaroo bal makru allayli wannahariith ta/muroonana an nakfura billahiwanajAAala lahu andadan waasarroo annadamatalamma raawoo alAAathaba wajaAAalna al-aghlalafee aAAnaqi allatheena kafaroo hal yujzawna illama kanoo yaAAmaloon","juz":22,"page":432},{"s":34,"a":34,"key":"34:34","ar":"وَمَآ أَرْسَلْنَا فِى قَرْيَةٍ مِّن نَّذِيرٍ إِلَّا قَالَ مُتْرَفُوهَآ إِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَـٰفِرُونَ","en":"And We did not send into a city any warner except that its affluent said, \"Indeed we, in that with which you were sent, are disbelievers.\"","tr":"Wama arsalna fee qaryatin minnatheerin illa qala mutrafooha innabima orsiltum bihi kafiroon","juz":22,"page":432},{"s":34,"a":35,"key":"34:35","ar":"وَقَالُوا۟ نَحْنُ أَكْثَرُ أَمْوَٰلًا وَأَوْلَـٰدًا وَمَا نَحْنُ بِمُعَذَّبِينَ","en":"And they1 said, \"We are more [than the believers] in wealth and children, and we are not to be punished.\"","tr":"Waqaloo nahnu aktharu amwalanwaawladan wama nahnu bimuAAaththabeen","juz":22,"page":432},{"s":34,"a":36,"key":"34:36","ar":"قُلْ إِنَّ رَبِّى يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"Say, \"Indeed, my Lord extends provision for whom He wills and restricts [it], but most of the people do not know.\"","tr":"Qul inna rabbee yabsutu arrizqaliman yashao wayaqdiru walakinna akthara annasila yaAAlamoon","juz":22,"page":432},{"s":34,"a":37,"key":"34:37","ar":"وَمَآ أَمْوَٰلُكُمْ وَلَآ أَوْلَـٰدُكُم بِٱلَّتِى تُقَرِّبُكُمْ عِندَنَا زُلْفَىٰٓ إِلَّا مَنْ ءَامَنَ وَعَمِلَ صَـٰلِحًا فَأُو۟لَـٰٓئِكَ لَهُمْ جَزَآءُ ٱلضِّعْفِ بِمَا عَمِلُوا۟ وَهُمْ فِى ٱلْغُرُفَـٰتِ ءَامِنُونَ","en":"And it is not your wealth or your children that bring you nearer to Us in position, but it is [by being] one who has believed and done righteousness. For them there will be the double reward for what they did, and they will be in the upper chambers [of Paradise], safe [and secure].","tr":"Wama amwalukum wala awladukumbillatee tuqarribukum AAindana zulfa illaman amana waAAamila salihan faola-ikalahum jazao addiAAfi bima AAamiloowahum fee alghurufati aminoon","juz":22,"page":432},{"s":34,"a":38,"key":"34:38","ar":"وَٱلَّذِينَ يَسْعَوْنَ فِىٓ ءَايَـٰتِنَا مُعَـٰجِزِينَ أُو۟لَـٰٓئِكَ فِى ٱلْعَذَابِ مُحْضَرُونَ","en":"And the ones who strive against Our verses to cause [them] failure1 - those will be brought into the punishment [to remain].","tr":"Wallatheena yasAAawna fee ayatinamuAAajizeena ola-ika fee alAAathabi muhdaroon","juz":22,"page":432},{"s":34,"a":39,"key":"34:39","ar":"قُلْ إِنَّ رَبِّى يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ لَهُۥ ۚ وَمَآ أَنفَقْتُم مِّن شَىْءٍ فَهُوَ يُخْلِفُهُۥ ۖ وَهُوَ خَيْرُ ٱلرَّٰزِقِينَ","en":"Say, \"Indeed, my Lord extends provision for whom He wills of His servants and restricts [it] for him. But whatever thing you spend [in His cause] - He will compensate it; and He is the best of providers.\"","tr":"Qul inna rabbee yabsutu arrizqaliman yashao min AAibadihi wayaqdiru lahu wamaanfaqtum min shay-in fahuwa yukhlifuhu wahuwa khayru arraziqeen","juz":22,"page":432},{"s":34,"a":40,"key":"34:40","ar":"وَيَوْمَ يَحْشُرُهُمْ جَمِيعًا ثُمَّ يَقُولُ لِلْمَلَـٰٓئِكَةِ أَهَـٰٓؤُلَآءِ إِيَّاكُمْ كَانُوا۟ يَعْبُدُونَ","en":"And [mention] the Day when He will gather them all and then say to the angels, \"Did these [people] used to worship you?\"","tr":"Wayawma yahshuruhum jameeAAan thummayaqoolu lilmala-ikati ahaola-i iyyakumkanoo yaAAbudoon","juz":22,"page":433},{"s":34,"a":41,"key":"34:41","ar":"قَالُوا۟ سُبْحَـٰنَكَ أَنتَ وَلِيُّنَا مِن دُونِهِم ۖ بَلْ كَانُوا۟ يَعْبُدُونَ ٱلْجِنَّ ۖ أَكْثَرُهُم بِهِم مُّؤْمِنُونَ","en":"They will say, \"Exalted are You! You, [O Allāh], are our benefactor excluding [i.e., not] them. Rather, they used to worship the jinn; most of them were believers in them.\"","tr":"Qaloo subhanaka anta waliyyunamin doonihim bal kanoo yaAAbudoona aljinna aktharuhumbihim mu/minoon","juz":22,"page":433},{"s":34,"a":42,"key":"34:42","ar":"فَٱلْيَوْمَ لَا يَمْلِكُ بَعْضُكُمْ لِبَعْضٍ نَّفْعًا وَلَا ضَرًّا وَنَقُولُ لِلَّذِينَ ظَلَمُوا۟ ذُوقُوا۟ عَذَابَ ٱلنَّارِ ٱلَّتِى كُنتُم بِهَا تُكَذِّبُونَ","en":"But today [i.e., the Day of Judgement] you do not hold for one another [the power of] benefit or harm, and We will say to those who wronged, \"Taste the punishment of the Fire, which you used to deny.\"","tr":"Falyawma la yamliku baAAdukumlibaAAdin nafAAan wala darran wanaqoolulillatheena thalamoo thooqoo AAathabaannari allatee kuntum biha tukaththiboon","juz":22,"page":433},{"s":34,"a":43,"key":"34:43","ar":"وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَـٰتُنَا بَيِّنَـٰتٍ قَالُوا۟ مَا هَـٰذَآ إِلَّا رَجُلٌ يُرِيدُ أَن يَصُدَّكُمْ عَمَّا كَانَ يَعْبُدُ ءَابَآؤُكُمْ وَقَالُوا۟ مَا هَـٰذَآ إِلَّآ إِفْكٌ مُّفْتَرًى ۚ وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِلْحَقِّ لَمَّا جَآءَهُمْ إِنْ هَـٰذَآ إِلَّا سِحْرٌ مُّبِينٌ","en":"And when Our verses are recited to them as clear evidences, they say, \"This is not but a man who wishes to avert you from that which your fathers were worshipping.\" And they say, \"This is not except a lie invented.\" And those who disbelieve say of the truth when it has come to them, \"This is not but obvious magic.\"","tr":"Wa-itha tutla AAalayhim ayatunabayyinatin qaloo ma hatha illarajulun yureedu an yasuddakum AAamma kanayaAAbudu abaokum waqaloo ma hathailla ifkun muftaran waqala allatheenakafaroo lilhaqqi lamma jaahum in hathailla sihrun mubeen","juz":22,"page":433},{"s":34,"a":44,"key":"34:44","ar":"وَمَآ ءَاتَيْنَـٰهُم مِّن كُتُبٍ يَدْرُسُونَهَا ۖ وَمَآ أَرْسَلْنَآ إِلَيْهِمْ قَبْلَكَ مِن نَّذِيرٍ","en":"And We had not given them any scriptures which they could study, and We had not sent to them before you, [O Muḥammad], any warner.","tr":"Wama ataynahum minkutubin yadrusoonaha wama arsalna ilayhimqablaka min natheer","juz":22,"page":433},{"s":34,"a":45,"key":"34:45","ar":"وَكَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ وَمَا بَلَغُوا۟ مِعْشَارَ مَآ ءَاتَيْنَـٰهُمْ فَكَذَّبُوا۟ رُسُلِى ۖ فَكَيْفَ كَانَ نَكِيرِ","en":"And those before them denied, and they [i.e., the people of Makkah] have not attained a tenth of what We had given them. But they [i.e., the former peoples] denied My messengers, so how [terrible] was My reproach.","tr":"Wakaththaba allatheena minqablihim wama balaghoo miAAshara ma ataynahumfakaththaboo rusulee fakayfa kana nakeer","juz":22,"page":433},{"s":34,"a":46,"key":"34:46","ar":"۞ قُلْ إِنَّمَآ أَعِظُكُم بِوَٰحِدَةٍ ۖ أَن تَقُومُوا۟ لِلَّهِ مَثْنَىٰ وَفُرَٰدَىٰ ثُمَّ تَتَفَكَّرُوا۟ ۚ مَا بِصَاحِبِكُم مِّن جِنَّةٍ ۚ إِنْ هُوَ إِلَّا نَذِيرٌ لَّكُم بَيْنَ يَدَىْ عَذَابٍ شَدِيدٍ","en":"Say, \"I only advise you of one [thing] - that you stand for Allāh, [seeking truth] in pairs and individually, and then give thought.\" There is not in your companion any madness. He is only a warner to you before a severe punishment.","tr":"Qul innama aAAithukumbiwahidatin an taqoomoo lillahi mathna wafuradathumma tatafakkaroo ma bisahibikum min jinnatin inhuwa illa natheerun lakum bayna yaday AAathabinshadeed","juz":22,"page":433},{"s":34,"a":47,"key":"34:47","ar":"قُلْ مَا سَأَلْتُكُم مِّنْ أَجْرٍ فَهُوَ لَكُمْ ۖ إِنْ أَجْرِىَ إِلَّا عَلَى ٱللَّهِ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ شَهِيدٌ","en":"Say, \"Whatever payment I might have asked of you - it is yours. My payment is only from Allāh, and He is, over all things, Witness.\"","tr":"Qul ma saaltukum min ajrin fahuwalakum in ajriya illa AAala Allahi wahuwaAAala kulli shay-in shaheed","juz":22,"page":433},{"s":34,"a":48,"key":"34:48","ar":"قُلْ إِنَّ رَبِّى يَقْذِفُ بِٱلْحَقِّ عَلَّـٰمُ ٱلْغُيُوبِ","en":"Say, \"Indeed, my Lord projects the truth, Knower of the unseen.\"","tr":"Qul inna rabbee yaqthifu bilhaqqiAAallamu alghuyoob","juz":22,"page":433},{"s":34,"a":49,"key":"34:49","ar":"قُلْ جَآءَ ٱلْحَقُّ وَمَا يُبْدِئُ ٱلْبَـٰطِلُ وَمَا يُعِيدُ","en":"Say, \"The truth has come, and falsehood can neither begin [anything] nor repeat [it].\"1","tr":"Qul jaa alhaqqu wamayubdi-o albatilu wama yuAAeed","juz":22,"page":434},{"s":34,"a":50,"key":"34:50","ar":"قُلْ إِن ضَلَلْتُ فَإِنَّمَآ أَضِلُّ عَلَىٰ نَفْسِى ۖ وَإِنِ ٱهْتَدَيْتُ فَبِمَا يُوحِىٓ إِلَىَّ رَبِّىٓ ۚ إِنَّهُۥ سَمِيعٌ قَرِيبٌ","en":"Say, \"If I should err, I would only err against myself. But if I am guided, it is by what my Lord reveals to me. Indeed, He is Hearing and near.\"","tr":"Qul in dalaltu fa-innama adilluAAala nafsee wa-ini ihtadaytu fabima yooheeilayya rabbee innahu sameeAAun qareeb","juz":22,"page":434},{"s":34,"a":51,"key":"34:51","ar":"وَلَوْ تَرَىٰٓ إِذْ فَزِعُوا۟ فَلَا فَوْتَ وَأُخِذُوا۟ مِن مَّكَانٍ قَرِيبٍ","en":"And if you could see1 when they are terrified but there is no escape, and they will be seized from a place nearby.","tr":"Walaw tara ith faziAAoo falafawta waokhithoo min makanin qareeb","juz":22,"page":434},{"s":34,"a":52,"key":"34:52","ar":"وَقَالُوٓا۟ ءَامَنَّا بِهِۦ وَأَنَّىٰ لَهُمُ ٱلتَّنَاوُشُ مِن مَّكَانٍۭ بَعِيدٍ","en":"And they will [then] say, \"We believe in it!\" But how for them will be the taking1 [of faith] from a place far away?2","tr":"Waqaloo amanna bihiwaanna lahumu attanawushu min makaninbaAAeed","juz":22,"page":434},{"s":34,"a":53,"key":"34:53","ar":"وَقَدْ كَفَرُوا۟ بِهِۦ مِن قَبْلُ ۖ وَيَقْذِفُونَ بِٱلْغَيْبِ مِن مَّكَانٍۭ بَعِيدٍ","en":"And they had already disbelieved in it before and would assault1 the unseen from a place far away.2","tr":"Waqad kafaroo bihi min qablu wayaqthifoonabilghaybi min makanin baAAeed","juz":22,"page":434},{"s":34,"a":54,"key":"34:54","ar":"وَحِيلَ بَيْنَهُمْ وَبَيْنَ مَا يَشْتَهُونَ كَمَا فُعِلَ بِأَشْيَاعِهِم مِّن قَبْلُ ۚ إِنَّهُمْ كَانُوا۟ فِى شَكٍّ مُّرِيبٍۭ","en":"And prevention will be placed between them and what they desire,1 as was done with their kind before. Indeed, they were in disquieting doubt [i.e., denial].","tr":"Waheela baynahum wabayna mayashtahoona kama fuAAila bi-ashyaAAihim min qabluinnahum kanoo fee shakkin mureeb","juz":22,"page":434},{"s":35,"a":1,"key":"35:1","ar":" ٱلْحَمْدُ لِلَّهِ فَاطِرِ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ جَاعِلِ ٱلْمَلَـٰٓئِكَةِ رُسُلًا أُو۟لِىٓ أَجْنِحَةٍ مَّثْنَىٰ وَثُلَـٰثَ وَرُبَـٰعَ ۚ يَزِيدُ فِى ٱلْخَلْقِ مَا يَشَآءُ ۚ إِنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"[All] praise is [due] to Allāh, Creator of the heavens and the earth, [who] made the angels messengers having wings, two or three or four. He increases in creation what He wills. Indeed, Allāh is over all things competent.","tr":"Alhamdu lillahi fatiri assamawatiwal-ardi jaAAili almala-ikatirusulan olee ajnihatin mathna wathulathawarubaAAa yazeedu fee alkhalqi ma yashaoinna Allaha AAala kulli shay-in qadeer","juz":22,"page":434},{"s":35,"a":2,"key":"35:2","ar":"مَّا يَفْتَحِ ٱللَّهُ لِلنَّاسِ مِن رَّحْمَةٍ فَلَا مُمْسِكَ لَهَا ۖ وَمَا يُمْسِكْ فَلَا مُرْسِلَ لَهُۥ مِنۢ بَعْدِهِۦ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Whatever Allāh grants to people of mercy - none can withhold it; and whatever He withholds - none can release it thereafter. And He is the Exalted in Might, the Wise.","tr":"Ma yaftahi Allahu linnasimin rahmatin fala mumsika laha wamayumsik fala mursila lahu min baAAdihi wahuwa alAAazeezu alhakeem","juz":22,"page":434},{"s":35,"a":3,"key":"35:3","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ ٱذْكُرُوا۟ نِعْمَتَ ٱللَّهِ عَلَيْكُمْ ۚ هَلْ مِنْ خَـٰلِقٍ غَيْرُ ٱللَّهِ يَرْزُقُكُم مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ ۚ لَآ إِلَـٰهَ إِلَّا هُوَ ۖ فَأَنَّىٰ تُؤْفَكُونَ","en":"O mankind, remember the favor of Allāh upon you. Is there any creator other than Allāh who provides for you from the heaven and earth? There is no deity except Him, so how are you deluded?","tr":"Ya ayyuha annasuothkuroo niAAmata Allahi AAalaykum hal min khaliqinghayru Allahi yarzuqukum mina assama-i wal-ardila ilaha illa huwa faanna tu/fakoon","juz":22,"page":434},{"s":35,"a":4,"key":"35:4","ar":"وَإِن يُكَذِّبُوكَ فَقَدْ كُذِّبَتْ رُسُلٌ مِّن قَبْلِكَ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ","en":"And if they deny you, [O Muḥammad] - already were messengers denied before you. And to Allāh are returned [all] matters.","tr":"Wa-in yukaththibooka faqad kuththibatrusulun min qablika wa-ila Allahi turjaAAu al-omoor","juz":22,"page":435},{"s":35,"a":5,"key":"35:5","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ ۖ فَلَا تَغُرَّنَّكُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا ۖ وَلَا يَغُرَّنَّكُم بِٱللَّهِ ٱلْغَرُورُ","en":"O mankind, indeed the promise of Allāh is truth, so let not the worldly life delude you and be not deceived about Allāh by the Deceiver [i.e., Satan].","tr":"Ya ayyuha annasuinna waAAda Allahi haqqun falataghurrannakumu alhayatu addunya walayaghurrannakum billahi algharoor","juz":22,"page":435},{"s":35,"a":6,"key":"35:6","ar":"إِنَّ ٱلشَّيْطَـٰنَ لَكُمْ عَدُوٌّ فَٱتَّخِذُوهُ عَدُوًّا ۚ إِنَّمَا يَدْعُوا۟ حِزْبَهُۥ لِيَكُونُوا۟ مِنْ أَصْحَـٰبِ ٱلسَّعِيرِ","en":"Indeed, Satan is an enemy to you; so take him as an enemy. He only invites his party to be among the companions of the Blaze.","tr":"Inna ashshaytana lakumAAaduwwun fattakhithoohu AAaduwwan innamayadAAoo hizbahu liyakoonoo min as-habi assaAAeer","juz":22,"page":435},{"s":35,"a":7,"key":"35:7","ar":"ٱلَّذِينَ كَفَرُوا۟ لَهُمْ عَذَابٌ شَدِيدٌ ۖ وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَهُم مَّغْفِرَةٌ وَأَجْرٌ كَبِيرٌ","en":"Those who disbelieve will have a severe punishment, and those who believe and do righteous deeds will have forgiveness and great reward.","tr":"Allatheena kafaroo lahum AAathabunshadeedun wallatheena amanoo waAAamiloo assalihatilahum maghfiratun waajrun kabeer","juz":22,"page":435},{"s":35,"a":8,"key":"35:8","ar":"أَفَمَن زُيِّنَ لَهُۥ سُوٓءُ عَمَلِهِۦ فَرَءَاهُ حَسَنًا ۖ فَإِنَّ ٱللَّهَ يُضِلُّ مَن يَشَآءُ وَيَهْدِى مَن يَشَآءُ ۖ فَلَا تَذْهَبْ نَفْسُكَ عَلَيْهِمْ حَسَرَٰتٍ ۚ إِنَّ ٱللَّهَ عَلِيمٌۢ بِمَا يَصْنَعُونَ","en":"Then is one to whom the evil of his deed has been made attractive so he considers it good [like one rightly guided]? For indeed, Allāh sends astray whom He wills and guides whom He wills. So do not let yourself perish over them in regret. Indeed, Allāh is Knowing of what they do.","tr":"Afaman zuyyina lahu soo-o AAamalihi faraahuhasanan fa-inna Allaha yudillu man yashaowayahdee man yashao fala tathhab nafsukaAAalayhim hasaratin inna Allaha AAaleemunbima yasnaAAoon","juz":22,"page":435},{"s":35,"a":9,"key":"35:9","ar":"وَٱللَّهُ ٱلَّذِىٓ أَرْسَلَ ٱلرِّيَـٰحَ فَتُثِيرُ سَحَابًا فَسُقْنَـٰهُ إِلَىٰ بَلَدٍ مَّيِّتٍ فَأَحْيَيْنَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا ۚ كَذَٰلِكَ ٱلنُّشُورُ","en":"And it is Allāh who sends the winds, and they stir the clouds, and We drive them to a dead land and give life thereby to the earth after its lifelessness. Thus is the resurrection.","tr":"Wallahu allathee arsalaarriyaha fatutheeru sahaban fasuqnahuila baladin mayyitin faahyayna bihi al-ardabaAAda mawtiha kathalika annushoor","juz":22,"page":435},{"s":35,"a":10,"key":"35:10","ar":"مَن كَانَ يُرِيدُ ٱلْعِزَّةَ فَلِلَّهِ ٱلْعِزَّةُ جَمِيعًا ۚ إِلَيْهِ يَصْعَدُ ٱلْكَلِمُ ٱلطَّيِّبُ وَٱلْعَمَلُ ٱلصَّـٰلِحُ يَرْفَعُهُۥ ۚ وَٱلَّذِينَ يَمْكُرُونَ ٱلسَّيِّـَٔاتِ لَهُمْ عَذَابٌ شَدِيدٌ ۖ وَمَكْرُ أُو۟لَـٰٓئِكَ هُوَ يَبُورُ","en":"Whoever desires honor [through power] - then to Allāh belongs all honor.1 To Him ascends good speech, and righteous work raises it.2 But they who plot evil deeds will have a severe punishment, and the plotting of those - it will perish.","tr":"Man kana yureedu alAAizzata falillahialAAizzatu jameeAAan ilayhi yasAAadu alkalimu attayyibuwalAAamalu assalihu yarfaAAuhu wallatheenayamkuroona assayyi-ati lahum AAathabunshadeedun wamakru ola-ika huwa yaboor","juz":22,"page":435},{"s":35,"a":11,"key":"35:11","ar":"وَٱللَّهُ خَلَقَكُم مِّن تُرَابٍ ثُمَّ مِن نُّطْفَةٍ ثُمَّ جَعَلَكُمْ أَزْوَٰجًا ۚ وَمَا تَحْمِلُ مِنْ أُنثَىٰ وَلَا تَضَعُ إِلَّا بِعِلْمِهِۦ ۚ وَمَا يُعَمَّرُ مِن مُّعَمَّرٍ وَلَا يُنقَصُ مِنْ عُمُرِهِۦٓ إِلَّا فِى كِتَـٰبٍ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌ","en":"And Allāh created you from dust, then from a sperm-drop; then He made you mates. And no female conceives nor does she give birth except with His knowledge. And no aged person is granted [additional] life nor is his lifespan lessened but that it is in a register. Indeed, that for Allāh is easy.","tr":"Wallahu khalaqakum min turabinthumma min nutfatin thumma jaAAalakum azwajan wamatahmilu min ontha wala tadaAAu illabiAAilmihi wama yuAAammaru min muAAammarin walayunqasu min AAumurihi illa fee kitabin inna thalikaAAala Allahi yaseer","juz":22,"page":435},{"s":35,"a":12,"key":"35:12","ar":"وَمَا يَسْتَوِى ٱلْبَحْرَانِ هَـٰذَا عَذْبٌ فُرَاتٌ سَآئِغٌ شَرَابُهُۥ وَهَـٰذَا مِلْحٌ أُجَاجٌ ۖ وَمِن كُلٍّ تَأْكُلُونَ لَحْمًا طَرِيًّا وَتَسْتَخْرِجُونَ حِلْيَةً تَلْبَسُونَهَا ۖ وَتَرَى ٱلْفُلْكَ فِيهِ مَوَاخِرَ لِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ","en":"And not alike are the two seas [i.e., bodies of water]. One is fresh and sweet, palatable for drinking, and one is salty and bitter. And from each you eat tender meat and extract ornaments which you wear, and you see the ships plowing through [them] that you might seek of His bounty; and perhaps you will be grateful.","tr":"Wama yastawee albahranihatha AAathbun furatun sa-ighun sharabuhuwahatha milhun ojajun wamin kullinta/kuloona lahman tariyyan watastakhrijoona hilyatantalbasoonaha watara alfulka feehi mawakhiralitabtaghoo min fadlihi walaAAallakum tashkuroon","juz":22,"page":436},{"s":35,"a":13,"key":"35:13","ar":"يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ كُلٌّ يَجْرِى لِأَجَلٍ مُّسَمًّى ۚ ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ لَهُ ٱلْمُلْكُ ۚ وَٱلَّذِينَ تَدْعُونَ مِن دُونِهِۦ مَا يَمْلِكُونَ مِن قِطْمِيرٍ","en":"He causes the night to enter the day, and He causes the day to enter the night and has subjected the sun and the moon - each running [its course] for a specified term. That is Allāh, your Lord; to Him belongs sovereignty. And those whom you invoke other than Him do not possess [as much as] the membrane of a date seed.","tr":"Yooliju allayla fee annahariwayooliju annahara fee allayli wasakhkhara ashshamsawalqamara kullun yajree li-ajalin musamman thalikumuAllahu rabbukum lahu almulku wallatheenatadAAoona min doonihi ma yamlikoona min qitmeer","juz":22,"page":436},{"s":35,"a":14,"key":"35:14","ar":"إِن تَدْعُوهُمْ لَا يَسْمَعُوا۟ دُعَآءَكُمْ وَلَوْ سَمِعُوا۟ مَا ٱسْتَجَابُوا۟ لَكُمْ ۖ وَيَوْمَ ٱلْقِيَـٰمَةِ يَكْفُرُونَ بِشِرْكِكُمْ ۚ وَلَا يُنَبِّئُكَ مِثْلُ خَبِيرٍ","en":"If you invoke them, they do not hear your supplication; and if they heard, they would not respond to you. And on the Day of Resurrection they will deny your association.1 And none can inform you like [one] Aware [of all matters].","tr":"In tadAAoohum la yasmaAAoo duAAaakumwalaw samiAAoo ma istajaboo lakum wayawma alqiyamatiyakfuroona bishirkikum wala yunabbi-oka mithlu khabeer","juz":22,"page":436},{"s":35,"a":15,"key":"35:15","ar":"۞ يَـٰٓأَيُّهَا ٱلنَّاسُ أَنتُمُ ٱلْفُقَرَآءُ إِلَى ٱللَّهِ ۖ وَٱللَّهُ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ","en":"O mankind, you are those in need of Allāh, while Allāh is the Free of need, the Praiseworthy.","tr":"Ya ayyuha annasuantumu alfuqarao ila Allahi wallahuhuwa alghaniyyu alhameed","juz":22,"page":436},{"s":35,"a":16,"key":"35:16","ar":"إِن يَشَأْ يُذْهِبْكُمْ وَيَأْتِ بِخَلْقٍ جَدِيدٍ","en":"If He wills, He can do away with you and bring forth a new creation.","tr":"In yasha/ yuthhibkum waya/tibikhalqin jadeed","juz":22,"page":436},{"s":35,"a":17,"key":"35:17","ar":"وَمَا ذَٰلِكَ عَلَى ٱللَّهِ بِعَزِيزٍ","en":"And that is for Allāh not difficult.","tr":"Wama thalika AAala AllahibiAAazeez","juz":22,"page":436},{"s":35,"a":18,"key":"35:18","ar":"وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَىٰ ۚ وَإِن تَدْعُ مُثْقَلَةٌ إِلَىٰ حِمْلِهَا لَا يُحْمَلْ مِنْهُ شَىْءٌ وَلَوْ كَانَ ذَا قُرْبَىٰٓ ۗ إِنَّمَا تُنذِرُ ٱلَّذِينَ يَخْشَوْنَ رَبَّهُم بِٱلْغَيْبِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ ۚ وَمَن تَزَكَّىٰ فَإِنَّمَا يَتَزَكَّىٰ لِنَفْسِهِۦ ۚ وَإِلَى ٱللَّهِ ٱلْمَصِيرُ","en":"And no bearer of burdens will bear the burden of another. And if a heavily laden soul calls [another] to [carry some of] its load, nothing of it will be carried, even if he should be a close relative. You can only warn those who fear their Lord unseen and have established prayer. And whoever purifies himself only purifies himself for [the benefit of] his soul. And to Allāh is the [final] destination.","tr":"Wala taziru waziratun wizraokhra wa-in tadAAu muthqalatun ila himlihala yuhmal minhu shay-on walaw kana thaqurba innama tunthiru allatheenayakhshawna rabbahum bilghaybi waaqamoo assalatawaman tazakka fa-innama yatazakka linafsihiwa-ila Allahi almaseer","juz":22,"page":436},{"s":35,"a":19,"key":"35:19","ar":"وَمَا يَسْتَوِى ٱلْأَعْمَىٰ وَٱلْبَصِيرُ","en":"Not equal are the blind and the seeing,","tr":"Wama yastawee al-aAAma walbaseer","juz":22,"page":437},{"s":35,"a":20,"key":"35:20","ar":"وَلَا ٱلظُّلُمَـٰتُ وَلَا ٱلنُّورُ","en":"Nor are the darknesses and the light,","tr":"Wala aththulumatuwala annoor","juz":22,"page":437},{"s":35,"a":21,"key":"35:21","ar":"وَلَا ٱلظِّلُّ وَلَا ٱلْحَرُورُ","en":"Nor are the shade and the heat,1","tr":"Wala aththilluwala alharoor","juz":22,"page":437},{"s":35,"a":22,"key":"35:22","ar":"وَمَا يَسْتَوِى ٱلْأَحْيَآءُ وَلَا ٱلْأَمْوَٰتُ ۚ إِنَّ ٱللَّهَ يُسْمِعُ مَن يَشَآءُ ۖ وَمَآ أَنتَ بِمُسْمِعٍ مَّن فِى ٱلْقُبُورِ","en":"And not equal are the living and the dead. Indeed, Allāh causes to hear whom He wills, but you cannot make hear those in the graves.1","tr":"Wama yastawee al-ahyaowala al-amwatu inna Allaha yusmiAAu man yashaowama anta bimusmiAAin man fee alquboor","juz":22,"page":437},{"s":35,"a":23,"key":"35:23","ar":"إِنْ أَنتَ إِلَّا نَذِيرٌ","en":"You, [O Muḥammad], are not but a warner.","tr":"In anta illa natheer","juz":22,"page":437},{"s":35,"a":24,"key":"35:24","ar":"إِنَّآ أَرْسَلْنَـٰكَ بِٱلْحَقِّ بَشِيرًا وَنَذِيرًا ۚ وَإِن مِّنْ أُمَّةٍ إِلَّا خَلَا فِيهَا نَذِيرٌ","en":"Indeed, We have sent you with the truth as a bringer of good tidings and a warner. And there was no nation but that there had passed within it a warner.","tr":"Inna arsalnaka bilhaqqibasheeran wanatheeran wa-in min ommatin illa khalafeeha natheer","juz":22,"page":437},{"s":35,"a":25,"key":"35:25","ar":"وَإِن يُكَذِّبُوكَ فَقَدْ كَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ جَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَـٰتِ وَبِٱلزُّبُرِ وَبِٱلْكِتَـٰبِ ٱلْمُنِيرِ","en":"And if they deny you - then already have those before them denied. Their messengers came to them with clear proofs and written ordinances and with the enlightening Scripture.","tr":"Wa-in yukaththibooka faqad kaththabaallatheena min qablihim jaat-hum rusuluhum bilbayyinatiwabizzuburi wabilkitabi almuneer","juz":22,"page":437},{"s":35,"a":26,"key":"35:26","ar":"ثُمَّ أَخَذْتُ ٱلَّذِينَ كَفَرُوا۟ ۖ فَكَيْفَ كَانَ نَكِيرِ","en":"Then I seized the ones who disbelieved, and how [terrible] was My reproach.","tr":"Thumma akhathtu allatheenakafaroo fakayfa kana nakeer","juz":22,"page":437},{"s":35,"a":27,"key":"35:27","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً فَأَخْرَجْنَا بِهِۦ ثَمَرَٰتٍ مُّخْتَلِفًا أَلْوَٰنُهَا ۚ وَمِنَ ٱلْجِبَالِ جُدَدٌۢ بِيضٌ وَحُمْرٌ مُّخْتَلِفٌ أَلْوَٰنُهَا وَغَرَابِيبُ سُودٌ","en":"Do you not see that Allāh sends down rain from the sky, and We produce thereby fruits of varying colors? And in the mountains are tracts, white and red of varying shades and [some] extremely black.","tr":"Alam tara anna Allaha anzala mina assama-imaan faakhrajna bihi thamaratin mukhtalifanalwanuha wamina aljibali judadun beedunwahumrun mukhtalifun alwanuha wagharabeebusood","juz":22,"page":437},{"s":35,"a":28,"key":"35:28","ar":"وَمِنَ ٱلنَّاسِ وَٱلدَّوَآبِّ وَٱلْأَنْعَـٰمِ مُخْتَلِفٌ أَلْوَٰنُهُۥ كَذَٰلِكَ ۗ إِنَّمَا يَخْشَى ٱللَّهَ مِنْ عِبَادِهِ ٱلْعُلَمَـٰٓؤُا۟ ۗ إِنَّ ٱللَّهَ عَزِيزٌ غَفُورٌ","en":"And among people and moving creatures and grazing livestock are various colors similarly. Only those fear Allāh, from among His servants, who have knowledge. Indeed, Allāh is Exalted in Might and Forgiving.","tr":"Wamina annasi waddawabbiwal-anAAami mukhtalifun alwanuhu kathalikainnama yakhsha Allaha min AAibadihialAAulamao inna Allaha AAazeezun ghafoor","juz":22,"page":437},{"s":35,"a":29,"key":"35:29","ar":"إِنَّ ٱلَّذِينَ يَتْلُونَ كِتَـٰبَ ٱللَّهِ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَأَنفَقُوا۟ مِمَّا رَزَقْنَـٰهُمْ سِرًّا وَعَلَانِيَةً يَرْجُونَ تِجَـٰرَةً لَّن تَبُورَ","en":"Indeed, those who recite the Book of Allāh and establish prayer and spend [in His cause] out of what We have provided them, secretly and publicly, [can] expect a transaction [i.e., profit] that will never perish -","tr":"Inna allatheena yatloona kitabaAllahi waaqamoo assalatawaanfaqoo mimma razaqnahum sirran waAAalaniyatanyarjoona tijaratan lan taboor","juz":22,"page":437},{"s":35,"a":30,"key":"35:30","ar":"لِيُوَفِّيَهُمْ أُجُورَهُمْ وَيَزِيدَهُم مِّن فَضْلِهِۦٓ ۚ إِنَّهُۥ غَفُورٌ شَكُورٌ","en":"That He may give them in full their rewards and increase for them of His bounty. Indeed, He is Forgiving and Appreciative.1","tr":"Liyuwaffiyahum ojoorahum wayazeedahum min fadlihiinnahu ghafoorun shakoor","juz":22,"page":437},{"s":35,"a":31,"key":"35:31","ar":"وَٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ مِنَ ٱلْكِتَـٰبِ هُوَ ٱلْحَقُّ مُصَدِّقًا لِّمَا بَيْنَ يَدَيْهِ ۗ إِنَّ ٱللَّهَ بِعِبَادِهِۦ لَخَبِيرٌۢ بَصِيرٌ","en":"And that which We have revealed to you, [O Muḥammad], of the Book is the truth, confirming what was before it. Indeed Allāh, of His servants, is Aware and Seeing.","tr":"Wallathee awhaynailayka mina alkitabi huwa alhaqqu musaddiqanlima bayna yadayhi inna Allaha biAAibadihilakhabeerun baseer","juz":22,"page":438},{"s":35,"a":32,"key":"35:32","ar":"ثُمَّ أَوْرَثْنَا ٱلْكِتَـٰبَ ٱلَّذِينَ ٱصْطَفَيْنَا مِنْ عِبَادِنَا ۖ فَمِنْهُمْ ظَالِمٌ لِّنَفْسِهِۦ وَمِنْهُم مُّقْتَصِدٌ وَمِنْهُمْ سَابِقٌۢ بِٱلْخَيْرَٰتِ بِإِذْنِ ٱللَّهِ ۚ ذَٰلِكَ هُوَ ٱلْفَضْلُ ٱلْكَبِيرُ","en":"Then We caused to inherit the Book those We have chosen of Our servants;1 and among them is he who wrongs himself [i.e., sins], and among them is he who is moderate, and among them is he who is foremost in good deeds by permission of Allāh. That [inheritance] is what is the great bounty.","tr":"Thumma awrathna alkitaba allatheenaistafayna min AAibadina faminhum thalimunlinafsihi waminhum muqtasidun waminhum sabiqun bilkhayratibi-ithni Allahi thalika huwa alfadlualkabeer","juz":22,"page":438},{"s":35,"a":33,"key":"35:33","ar":"جَنَّـٰتُ عَدْنٍ يَدْخُلُونَهَا يُحَلَّوْنَ فِيهَا مِنْ أَسَاوِرَ مِن ذَهَبٍ وَلُؤْلُؤًا ۖ وَلِبَاسُهُمْ فِيهَا حَرِيرٌ","en":"[For them are] gardens of perpetual residence which they will enter. They will be adorned therein with bracelets of gold and pearls, and their garments therein will be silk.","tr":"Jannatu AAadnin yadkhuloonahayuhallawna feeha min asawira min thahabinwalu/lu-an walibasuhum feeha hareer","juz":22,"page":438},{"s":35,"a":34,"key":"35:34","ar":"وَقَالُوا۟ ٱلْحَمْدُ لِلَّهِ ٱلَّذِىٓ أَذْهَبَ عَنَّا ٱلْحَزَنَ ۖ إِنَّ رَبَّنَا لَغَفُورٌ شَكُورٌ","en":"And they will say, \"Praise to Allāh, who has removed from us [all] sorrow. Indeed, our Lord is Forgiving and Appreciative -","tr":"Waqaloo alhamdu lillahiallathee athhaba AAanna alhazana innarabbana laghafoorun shakoor","juz":22,"page":438},{"s":35,"a":35,"key":"35:35","ar":"ٱلَّذِىٓ أَحَلَّنَا دَارَ ٱلْمُقَامَةِ مِن فَضْلِهِۦ لَا يَمَسُّنَا فِيهَا نَصَبٌ وَلَا يَمَسُّنَا فِيهَا لُغُوبٌ","en":"He who has settled us in the home of duration [i.e., Paradise] out of His bounty. There touches us not in it any fatigue, and there touches us not in it weariness [of mind].\"","tr":"Allathee ahallana daraalmuqamati min fadlihi la yamassunafeeha nasabun wala yamassuna feehalughoob","juz":22,"page":438},{"s":35,"a":36,"key":"35:36","ar":"وَٱلَّذِينَ كَفَرُوا۟ لَهُمْ نَارُ جَهَنَّمَ لَا يُقْضَىٰ عَلَيْهِمْ فَيَمُوتُوا۟ وَلَا يُخَفَّفُ عَنْهُم مِّنْ عَذَابِهَا ۚ كَذَٰلِكَ نَجْزِى كُلَّ كَفُورٍ","en":"And for those who disbelieve will be the fire of Hell. [Death] is not decreed for them1 so they may die, nor will its torment be lightened for them. Thus do We recompense every ungrateful one.","tr":"Wallatheena kafaroo lahum narujahannama la yuqda AAalayhim fayamootoo walayukhaffafu AAanhum min AAathabiha kathalikanajzee kulla kafoor","juz":22,"page":438},{"s":35,"a":37,"key":"35:37","ar":"وَهُمْ يَصْطَرِخُونَ فِيهَا رَبَّنَآ أَخْرِجْنَا نَعْمَلْ صَـٰلِحًا غَيْرَ ٱلَّذِى كُنَّا نَعْمَلُ ۚ أَوَلَمْ نُعَمِّرْكُم مَّا يَتَذَكَّرُ فِيهِ مَن تَذَكَّرَ وَجَآءَكُمُ ٱلنَّذِيرُ ۖ فَذُوقُوا۟ فَمَا لِلظَّـٰلِمِينَ مِن نَّصِيرٍ","en":"And they will cry out therein, \"Our Lord, remove us;1 we will do righteousness - other than what we were doing!\" But did We not grant you life enough for whoever would remember therein to remember, and the warner had come to you? So taste [the punishment], for there is not for the wrongdoers any helper.","tr":"Wahum yastarikhoona feeharabbana akhrijna naAAmal salihanghayra allathee kunna naAAmalu awa lam nuAAammirkumma yatathakkaru feehi man tathakkara wajaakumuannatheeru fathooqoo fama liththalimeenamin naseer","juz":22,"page":438},{"s":35,"a":38,"key":"35:38","ar":"إِنَّ ٱللَّهَ عَـٰلِمُ غَيْبِ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"Indeed, Allāh is Knower of the unseen [aspects] of the heavens and earth. Indeed, He is Knowing of that within the breasts.","tr":"Inna Allaha AAalimu ghaybi assamawatiwal-ardi innahu AAaleemun bithati assudoor","juz":22,"page":438},{"s":35,"a":39,"key":"35:39","ar":"هُوَ ٱلَّذِى جَعَلَكُمْ خَلَـٰٓئِفَ فِى ٱلْأَرْضِ ۚ فَمَن كَفَرَ فَعَلَيْهِ كُفْرُهُۥ ۖ وَلَا يَزِيدُ ٱلْكَـٰفِرِينَ كُفْرُهُمْ عِندَ رَبِّهِمْ إِلَّا مَقْتًا ۖ وَلَا يَزِيدُ ٱلْكَـٰفِرِينَ كُفْرُهُمْ إِلَّا خَسَارًا","en":"It is He who has made you successors upon the earth. And whoever disbelieves - upon him will be [the consequence of] his disbelief. And the disbelief of the disbelievers does not increase them in the sight of their Lord except in hatred; and the disbelief of the disbelievers does not increase them except in loss.","tr":"Huwa allathee jaAAalakum khala-ifafee al-ardi faman kafara faAAalayhi kufruhu walayazeedu alkafireena kufruhum AAinda rabbihim illamaqtan wala yazeedu alkafireena kufruhum illakhasara","juz":22,"page":439},{"s":35,"a":40,"key":"35:40","ar":"قُلْ أَرَءَيْتُمْ شُرَكَآءَكُمُ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ أَرُونِى مَاذَا خَلَقُوا۟ مِنَ ٱلْأَرْضِ أَمْ لَهُمْ شِرْكٌ فِى ٱلسَّمَـٰوَٰتِ أَمْ ءَاتَيْنَـٰهُمْ كِتَـٰبًا فَهُمْ عَلَىٰ بَيِّنَتٍ مِّنْهُ ۚ بَلْ إِن يَعِدُ ٱلظَّـٰلِمُونَ بَعْضُهُم بَعْضًا إِلَّا غُرُورًا","en":"Say, \"Have you considered1 your 'partners' whom you invoke besides Allāh? Show me what they have created from the earth, or have they partnership [with Him] in the heavens? Or have We given them a book so they are [standing] on evidence therefrom? [No], rather, the wrongdoers do not promise each other except delusion.\"2","tr":"Qul araaytum shurakaakumu allatheenatadAAoona min dooni Allahi aroonee matha khalaqoomina al-ardi am lahum shirkun fee assamawatiam ataynahum kitaban fahum AAalabayyinatin minhu bal in yaAAidu aththalimoonabaAAduhum baAAdan illa ghuroora","juz":22,"page":439},{"s":35,"a":41,"key":"35:41","ar":"۞ إِنَّ ٱللَّهَ يُمْسِكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ أَن تَزُولَا ۚ وَلَئِن زَالَتَآ إِنْ أَمْسَكَهُمَا مِنْ أَحَدٍ مِّنۢ بَعْدِهِۦٓ ۚ إِنَّهُۥ كَانَ حَلِيمًا غَفُورًا","en":"Indeed, Allāh holds the heavens and the earth, lest they cease. And if they should cease, no one could hold them [in place] after Him. Indeed, He is Forbearing1 and Forgiving.","tr":"Inna Allaha yumsiku assamawatiwal-arda an tazoola wala-in zalatain amsakahuma min ahadin min baAAdihi innahu kanahaleeman ghafoora","juz":22,"page":439},{"s":35,"a":42,"key":"35:42","ar":"وَأَقْسَمُوا۟ بِٱللَّهِ جَهْدَ أَيْمَـٰنِهِمْ لَئِن جَآءَهُمْ نَذِيرٌ لَّيَكُونُنَّ أَهْدَىٰ مِنْ إِحْدَى ٱلْأُمَمِ ۖ فَلَمَّا جَآءَهُمْ نَذِيرٌ مَّا زَادَهُمْ إِلَّا نُفُورًا","en":"And they swore by Allāh their strongest oaths that if a warner came to them, they would be more guided than [any] one of the [previous] nations. But when a warner came to them, it did not increase them except in aversion","tr":"Waaqsamoo billahi jahda aymanihimla-in jaahum natheerun layakoonunna ahda minihda al-omami falamma jaahum natheerunma zadahum illa nufoora","juz":22,"page":439},{"s":35,"a":43,"key":"35:43","ar":"ٱسْتِكْبَارًا فِى ٱلْأَرْضِ وَمَكْرَ ٱلسَّيِّئِ ۚ وَلَا يَحِيقُ ٱلْمَكْرُ ٱلسَّيِّئُ إِلَّا بِأَهْلِهِۦ ۚ فَهَلْ يَنظُرُونَ إِلَّا سُنَّتَ ٱلْأَوَّلِينَ ۚ فَلَن تَجِدَ لِسُنَّتِ ٱللَّهِ تَبْدِيلًا ۖ وَلَن تَجِدَ لِسُنَّتِ ٱللَّهِ تَحْوِيلًا","en":"[Due to] arrogance in the land and plotting of evil; but the evil plot does not encompass except its own people. Then do they await except the way [i.e., fate] of the former peoples? But you will never find in the way [i.e., established method] of Allāh any change, and you will never find in the way of Allāh1 any alteration.2","tr":"Istikbaran fee al-ardi wamakraassayyi-i wala yaheequ almakru assayyi-oilla bi-ahlihi fahal yanthuroona illasunnata al-awwaleena falan tajida lisunnati Allahitabdeelan walan tajida lisunnati Allahi tahweela","juz":22,"page":439},{"s":35,"a":44,"key":"35:44","ar":"أَوَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ وَكَانُوٓا۟ أَشَدَّ مِنْهُمْ قُوَّةً ۚ وَمَا كَانَ ٱللَّهُ لِيُعْجِزَهُۥ مِن شَىْءٍ فِى ٱلسَّمَـٰوَٰتِ وَلَا فِى ٱلْأَرْضِ ۚ إِنَّهُۥ كَانَ عَلِيمًا قَدِيرًا","en":"Have they not traveled through the land and observed how was the end of those before them? And they were greater than them in power. But Allāh is not to be caused failure [i.e., prevented] by anything in the heavens or on the earth. Indeed, He is ever Knowing and Competent.","tr":"Awa lam yaseeroo fee al-ardi fayanthurookayfa kana AAaqibatu allatheena min qablihimwakanoo ashadda minhum quwwatan wama kanaAllahu liyuAAjizahu min shay-in fee assamawatiwala fee al-ardi innahu kana AAaleemanqadeera","juz":22,"page":439},{"s":35,"a":45,"key":"35:45","ar":"وَلَوْ يُؤَاخِذُ ٱللَّهُ ٱلنَّاسَ بِمَا كَسَبُوا۟ مَا تَرَكَ عَلَىٰ ظَهْرِهَا مِن دَآبَّةٍ وَلَـٰكِن يُؤَخِّرُهُمْ إِلَىٰٓ أَجَلٍ مُّسَمًّى ۖ فَإِذَا جَآءَ أَجَلُهُمْ فَإِنَّ ٱللَّهَ كَانَ بِعِبَادِهِۦ بَصِيرًۢا","en":"And if Allāh were to impose blame on the people for what they have earned, He would not leave upon it [i.e., the earth] any creature. But He defers them for a specified term. And when their time comes, then indeed Allāh has ever been, of His servants, Seeing.","tr":"Walaw yu-akhithu Allahuannasa bima kasaboo ma taraka AAalathahriha min dabbatin walakinyu-akhkhiruhum ila ajalin musamman fa-itha jaaajaluhum fa-inna Allaha kana biAAibadihi baseera","juz":22,"page":440},{"s":36,"a":1,"key":"36:1","ar":" يسٓ","en":"Yā, Seen.1","tr":"Ya-seen","juz":22,"page":440},{"s":36,"a":2,"key":"36:2","ar":"وَٱلْقُرْءَانِ ٱلْحَكِيمِ","en":"By the wise1 Qur’ān,","tr":"Walqur-ani alhakeem","juz":22,"page":440},{"s":36,"a":3,"key":"36:3","ar":"إِنَّكَ لَمِنَ ٱلْمُرْسَلِينَ","en":"Indeed you, [O Muḥammad], are from among the messengers,","tr":"Innaka lamina almursaleen","juz":22,"page":440},{"s":36,"a":4,"key":"36:4","ar":"عَلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"On a straight path.","tr":"AAala siratin mustaqeem","juz":22,"page":440},{"s":36,"a":5,"key":"36:5","ar":"تَنزِيلَ ٱلْعَزِيزِ ٱلرَّحِيمِ","en":"[This is] a revelation of the Exalted in Might, the Merciful,","tr":"Tanzeela alAAazeezi arraheem","juz":22,"page":440},{"s":36,"a":6,"key":"36:6","ar":"لِتُنذِرَ قَوْمًا مَّآ أُنذِرَ ءَابَآؤُهُمْ فَهُمْ غَـٰفِلُونَ","en":"That you may warn a people whose forefathers were not warned, so they are unaware.","tr":"Litunthira qawman ma onthiraabaohum fahum ghafiloon","juz":22,"page":440},{"s":36,"a":7,"key":"36:7","ar":"لَقَدْ حَقَّ ٱلْقَوْلُ عَلَىٰٓ أَكْثَرِهِمْ فَهُمْ لَا يُؤْمِنُونَ","en":"Already the word [i.e., decree] has come into effect upon most of them, so they do not believe.","tr":"Laqad haqqa alqawlu AAalaaktharihim fahum la yu/minoon","juz":22,"page":440},{"s":36,"a":8,"key":"36:8","ar":"إِنَّا جَعَلْنَا فِىٓ أَعْنَـٰقِهِمْ أَغْلَـٰلًا فَهِىَ إِلَى ٱلْأَذْقَانِ فَهُم مُّقْمَحُونَ","en":"Indeed, We have put shackles on their necks, and they are to their chins, so they are with heads [kept] aloft.","tr":"Inna jaAAalna fee aAAnaqihimaghlalan fahiya ila al-athqani fahummuqmahoon","juz":22,"page":440},{"s":36,"a":9,"key":"36:9","ar":"وَجَعَلْنَا مِنۢ بَيْنِ أَيْدِيهِمْ سَدًّا وَمِنْ خَلْفِهِمْ سَدًّا فَأَغْشَيْنَـٰهُمْ فَهُمْ لَا يُبْصِرُونَ","en":"And We have put before them a barrier and behind them a barrier and covered them, so they do not see.","tr":"WajaAAalna min bayni aydeehim saddanwamin khalfihim saddan faaghshaynahum fahum la yubsiroon","juz":22,"page":440},{"s":36,"a":10,"key":"36:10","ar":"وَسَوَآءٌ عَلَيْهِمْ ءَأَنذَرْتَهُمْ أَمْ لَمْ تُنذِرْهُمْ لَا يُؤْمِنُونَ","en":"And it is all the same for them whether you warn them or do not warn them - they will not believe.","tr":"Wasawaon AAalayhim aanthartahumam lam tunthirhum la yu/minoon","juz":22,"page":440},{"s":36,"a":11,"key":"36:11","ar":"إِنَّمَا تُنذِرُ مَنِ ٱتَّبَعَ ٱلذِّكْرَ وَخَشِىَ ٱلرَّحْمَـٰنَ بِٱلْغَيْبِ ۖ فَبَشِّرْهُ بِمَغْفِرَةٍ وَأَجْرٍ كَرِيمٍ","en":"You can only warn one who follows the message and fears the Most Merciful unseen. So give him good tidings of forgiveness and noble reward.","tr":"Innama tunthiru mani ittabaAAaaththikra wakhashiya arrahmanabilghaybi fabashshirhu bimaghfiratin waajrin kareem","juz":22,"page":440},{"s":36,"a":12,"key":"36:12","ar":"إِنَّا نَحْنُ نُحْىِ ٱلْمَوْتَىٰ وَنَكْتُبُ مَا قَدَّمُوا۟ وَءَاثَـٰرَهُمْ ۚ وَكُلَّ شَىْءٍ أَحْصَيْنَـٰهُ فِىٓ إِمَامٍ مُّبِينٍ","en":"Indeed, it is We who bring the dead to life and record what they have put forth and what they left behind, and all things We have enumerated in a clear register.","tr":"Inna nahnu nuhyeealmawta wanaktubu ma qaddamoo waatharahumwakulla shay-in ahsaynahu fee imamin mubeen","juz":22,"page":440},{"s":36,"a":13,"key":"36:13","ar":"وَٱضْرِبْ لَهُم مَّثَلًا أَصْحَـٰبَ ٱلْقَرْيَةِ إِذْ جَآءَهَا ٱلْمُرْسَلُونَ","en":"And present to them an example: the people of the city, when the messengers came to it -","tr":"Wadrib lahum mathalan as-habaalqaryati ith jaaha almursaloon","juz":22,"page":441},{"s":36,"a":14,"key":"36:14","ar":"إِذْ أَرْسَلْنَآ إِلَيْهِمُ ٱثْنَيْنِ فَكَذَّبُوهُمَا فَعَزَّزْنَا بِثَالِثٍ فَقَالُوٓا۟ إِنَّآ إِلَيْكُم مُّرْسَلُونَ","en":"When We sent to them two but they denied them, so We strengthened [them] with a third, and they said, \"Indeed, we are messengers to you.\"","tr":"Ith arsalna ilayhimu ithnaynifakaththaboohuma faAAazzazna bithalithinfaqaloo inna ilaykum mursaloon","juz":22,"page":441},{"s":36,"a":15,"key":"36:15","ar":"قَالُوا۟ مَآ أَنتُمْ إِلَّا بَشَرٌ مِّثْلُنَا وَمَآ أَنزَلَ ٱلرَّحْمَـٰنُ مِن شَىْءٍ إِنْ أَنتُمْ إِلَّا تَكْذِبُونَ","en":"They said, \"You are not but human beings like us, and the Most Merciful has not revealed a thing. You are only telling lies.\"","tr":"Qaloo ma antum illabasharun mithluna wama anzala arrahmanumin shay-in in antum illa takthiboon","juz":22,"page":441},{"s":36,"a":16,"key":"36:16","ar":"قَالُوا۟ رَبُّنَا يَعْلَمُ إِنَّآ إِلَيْكُمْ لَمُرْسَلُونَ","en":"They said, \"Our Lord knows that we are messengers to you,","tr":"Qaloo rabbuna yaAAlamu innailaykum lamursaloon","juz":22,"page":441},{"s":36,"a":17,"key":"36:17","ar":"وَمَا عَلَيْنَآ إِلَّا ٱلْبَلَـٰغُ ٱلْمُبِينُ","en":"And we are not responsible except for clear notification.\"","tr":"Wama AAalayna illaalbalaghu almubeen","juz":22,"page":441},{"s":36,"a":18,"key":"36:18","ar":"قَالُوٓا۟ إِنَّا تَطَيَّرْنَا بِكُمْ ۖ لَئِن لَّمْ تَنتَهُوا۟ لَنَرْجُمَنَّكُمْ وَلَيَمَسَّنَّكُم مِّنَّا عَذَابٌ أَلِيمٌ","en":"They said, \"Indeed, we consider you a bad omen. If you do not desist, we will surely stone you, and there will surely touch you, from us, a painful punishment.\"","tr":"Qaloo inna tatayyarnabikum la-in lam tantahoo lanarjumannakum walayamassannakum minnaAAathabun aleem","juz":22,"page":441},{"s":36,"a":19,"key":"36:19","ar":"قَالُوا۟ طَـٰٓئِرُكُم مَّعَكُمْ ۚ أَئِن ذُكِّرْتُم ۚ بَلْ أَنتُمْ قَوْمٌ مُّسْرِفُونَ","en":"They said, \"Your omen [i.e., fate] is with yourselves. Is it1 because you were reminded? Rather, you are a transgressing people.\"","tr":"Qaloo ta-irukum maAAakum a-in thukkirtumbal antum qawmun musrifoon","juz":22,"page":441},{"s":36,"a":20,"key":"36:20","ar":"وَجَآءَ مِنْ أَقْصَا ٱلْمَدِينَةِ رَجُلٌ يَسْعَىٰ قَالَ يَـٰقَوْمِ ٱتَّبِعُوا۟ ٱلْمُرْسَلِينَ","en":"And there came from the farthest end of the city a man, running. He said, \"O my people, follow the messengers.","tr":"Wajaa min aqsa almadeenatirajulun yasAAa qala ya qawmi ittabiAAooalmursaleen","juz":22,"page":441},{"s":36,"a":21,"key":"36:21","ar":"ٱتَّبِعُوا۟ مَن لَّا يَسْـَٔلُكُمْ أَجْرًا وَهُم مُّهْتَدُونَ","en":"Follow those who do not ask of you [any] payment, and they are [rightly] guided.","tr":"IttabiAAoo man la yas-alukum ajranwahum muhtadoon","juz":22,"page":441},{"s":36,"a":22,"key":"36:22","ar":"وَمَا لِىَ لَآ أَعْبُدُ ٱلَّذِى فَطَرَنِى وَإِلَيْهِ تُرْجَعُونَ","en":"And why should I not worship He who created me and to whom you will be returned?","tr":"Wama liya la aAAbudu allatheefataranee wa-ilayhi turjaAAoon","juz":22,"page":441},{"s":36,"a":23,"key":"36:23","ar":"ءَأَتَّخِذُ مِن دُونِهِۦٓ ءَالِهَةً إِن يُرِدْنِ ٱلرَّحْمَـٰنُ بِضُرٍّ لَّا تُغْنِ عَنِّى شَفَـٰعَتُهُمْ شَيْـًٔا وَلَا يُنقِذُونِ","en":"Should I take other than Him [false] deities [while], if the Most Merciful intends for me some adversity, their intercession will not avail me at all, nor can they save me?","tr":"Aattakhithu min doonihi alihatanin yuridni arrahmanu bidurrin la tughniAAannee shafaAAatuhum shay-an wala yunqithoon","juz":22,"page":441},{"s":36,"a":24,"key":"36:24","ar":"إِنِّىٓ إِذًا لَّفِى ضَلَـٰلٍ مُّبِينٍ","en":"Indeed, I would then be in manifest error.","tr":"Innee ithan lafee dalalinmubeen","juz":22,"page":441},{"s":36,"a":25,"key":"36:25","ar":"إِنِّىٓ ءَامَنتُ بِرَبِّكُمْ فَٱسْمَعُونِ","en":"Indeed, I have believed in your Lord, so listen to me.\"","tr":"Innee amantu birabbikum fasmaAAoon","juz":22,"page":441},{"s":36,"a":26,"key":"36:26","ar":"قِيلَ ٱدْخُلِ ٱلْجَنَّةَ ۖ قَالَ يَـٰلَيْتَ قَوْمِى يَعْلَمُونَ","en":"It was said, \"Enter Paradise.\"1 He said, \"I wish my people could know","tr":"Qeela odkhuli aljannata qala yalayta qawmee yaAAlamoon","juz":22,"page":441},{"s":36,"a":27,"key":"36:27","ar":"بِمَا غَفَرَ لِى رَبِّى وَجَعَلَنِى مِنَ ٱلْمُكْرَمِينَ","en":"Of how my Lord has forgiven me and placed me among the honored.\"","tr":"Bima ghafara lee rabbee wajaAAalaneemina almukrameen","juz":22,"page":441},{"s":36,"a":28,"key":"36:28","ar":"۞ وَمَآ أَنزَلْنَا عَلَىٰ قَوْمِهِۦ مِنۢ بَعْدِهِۦ مِن جُندٍ مِّنَ ٱلسَّمَآءِ وَمَا كُنَّا مُنزِلِينَ","en":"And We did not send down upon his people after him any soldiers from the heaven, nor would We have done so.","tr":"Wama anzalna AAalaqawmihi min baAAdihi min jundin mina assama-i wamakunna munzileen","juz":23,"page":442},{"s":36,"a":29,"key":"36:29","ar":"إِن كَانَتْ إِلَّا صَيْحَةً وَٰحِدَةً فَإِذَا هُمْ خَـٰمِدُونَ","en":"It was not but one shout,1 and immediately they were extinguished.","tr":"In kanat illa sayhatanwahidatan fa-itha hum khamidoon","juz":23,"page":442},{"s":36,"a":30,"key":"36:30","ar":"يَـٰحَسْرَةً عَلَى ٱلْعِبَادِ ۚ مَا يَأْتِيهِم مِّن رَّسُولٍ إِلَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"How regretful for the servants. There did not come to them any messenger except that they used to ridicule him.","tr":"Ya hasratan AAalaalAAibadi ma ya/teehim min rasoolin illa kanoobihi yastahzi-oon","juz":23,"page":442},{"s":36,"a":31,"key":"36:31","ar":"أَلَمْ يَرَوْا۟ كَمْ أَهْلَكْنَا قَبْلَهُم مِّنَ ٱلْقُرُونِ أَنَّهُمْ إِلَيْهِمْ لَا يَرْجِعُونَ","en":"Have they not considered how many generations We destroyed before them - that they to them1 will not return?","tr":"Alam yaraw kam ahlakna qablahum minaalqurooni annahum ilayhim la yarjiAAoon","juz":23,"page":442},{"s":36,"a":32,"key":"36:32","ar":"وَإِن كُلٌّ لَّمَّا جَمِيعٌ لَّدَيْنَا مُحْضَرُونَ","en":"And indeed, all of them will yet be brought present before Us.","tr":"Wa-in kullun lamma jameeAAun ladaynamuhdaroon","juz":23,"page":442},{"s":36,"a":33,"key":"36:33","ar":"وَءَايَةٌ لَّهُمُ ٱلْأَرْضُ ٱلْمَيْتَةُ أَحْيَيْنَـٰهَا وَأَخْرَجْنَا مِنْهَا حَبًّا فَمِنْهُ يَأْكُلُونَ","en":"And a sign for them is the dead earth. We have brought it to life and brought forth from it grain, and from it they eat.","tr":"Waayatun lahumu al-ardualmaytatu ahyaynaha waakhrajna minhahabban faminhu ya/kuloon","juz":23,"page":442},{"s":36,"a":34,"key":"36:34","ar":"وَجَعَلْنَا فِيهَا جَنَّـٰتٍ مِّن نَّخِيلٍ وَأَعْنَـٰبٍ وَفَجَّرْنَا فِيهَا مِنَ ٱلْعُيُونِ","en":"And We placed therein gardens of palm trees and grapevines and caused to burst forth therefrom some springs -","tr":"WajaAAalna feeha jannatinmin nakheelin waaAAnabin wafajjarna feehamina alAAuyoon","juz":23,"page":442},{"s":36,"a":35,"key":"36:35","ar":"لِيَأْكُلُوا۟ مِن ثَمَرِهِۦ وَمَا عَمِلَتْهُ أَيْدِيهِمْ ۖ أَفَلَا يَشْكُرُونَ","en":"That they may eat of His fruit.1 And their hands have not produced it,2 so will they not be grateful?","tr":"Liya/kuloo min thamarihi wamaAAamilat-hu aydeehim afala yashkuroon","juz":23,"page":442},{"s":36,"a":36,"key":"36:36","ar":"سُبْحَـٰنَ ٱلَّذِى خَلَقَ ٱلْأَزْوَٰجَ كُلَّهَا مِمَّا تُنۢبِتُ ٱلْأَرْضُ وَمِنْ أَنفُسِهِمْ وَمِمَّا لَا يَعْلَمُونَ","en":"Exalted is He who created all pairs1 - from what the earth grows and from themselves and from that which they do not know.","tr":"Subhana allathee khalaqaal-azwaja kullaha mimma tunbitu al-arduwamin anfusihim wamimma la yaAAlamoon","juz":23,"page":442},{"s":36,"a":37,"key":"36:37","ar":"وَءَايَةٌ لَّهُمُ ٱلَّيْلُ نَسْلَخُ مِنْهُ ٱلنَّهَارَ فَإِذَا هُم مُّظْلِمُونَ","en":"And a sign for them is the night. We remove1 from it the [light of] day, so they are [left] in darkness.","tr":"Waayatun lahumu allaylu naslakhuminhu annahara fa-itha hum muthlimoon","juz":23,"page":442},{"s":36,"a":38,"key":"36:38","ar":"وَٱلشَّمْسُ تَجْرِى لِمُسْتَقَرٍّ لَّهَا ۚ ذَٰلِكَ تَقْدِيرُ ٱلْعَزِيزِ ٱلْعَلِيمِ","en":"And the sun runs [on course] toward its stopping point. That is the determination of the Exalted in Might, the Knowing.","tr":"Washshamsu tajree limustaqarrin lahathalika taqdeeru alAAazeezi alAAaleem","juz":23,"page":442},{"s":36,"a":39,"key":"36:39","ar":"وَٱلْقَمَرَ قَدَّرْنَـٰهُ مَنَازِلَ حَتَّىٰ عَادَ كَٱلْعُرْجُونِ ٱلْقَدِيمِ","en":"And the moon - We have determined for it phases, until it returns [appearing] like the old date stalk.","tr":"Walqamara qaddarnahu manazilahatta AAada kalAAurjooni alqadeem","juz":23,"page":442},{"s":36,"a":40,"key":"36:40","ar":"لَا ٱلشَّمْسُ يَنۢبَغِى لَهَآ أَن تُدْرِكَ ٱلْقَمَرَ وَلَا ٱلَّيْلُ سَابِقُ ٱلنَّهَارِ ۚ وَكُلٌّ فِى فَلَكٍ يَسْبَحُونَ","en":"It is not allowable [i.e., possible] for the sun to reach the moon, nor does the night overtake the day, but each, in an orbit, is swimming.","tr":"La ashshamsu yanbaghee lahaan tudrika alqamara wala allaylu sabiqu annahariwakullun fee falakin yasbahoon","juz":23,"page":442},{"s":36,"a":41,"key":"36:41","ar":"وَءَايَةٌ لَّهُمْ أَنَّا حَمَلْنَا ذُرِّيَّتَهُمْ فِى ٱلْفُلْكِ ٱلْمَشْحُونِ","en":"And a sign for them is that We carried their forefathers1 in a laden ship.","tr":"Waayatun lahum anna hamalnathurriyyatahum fee alfulki almashhoon","juz":23,"page":443},{"s":36,"a":42,"key":"36:42","ar":"وَخَلَقْنَا لَهُم مِّن مِّثْلِهِۦ مَا يَرْكَبُونَ","en":"And We created for them from the likes of it that which they ride.","tr":"Wakhalaqna lahum min mithlihi mayarkaboon","juz":23,"page":443},{"s":36,"a":43,"key":"36:43","ar":"وَإِن نَّشَأْ نُغْرِقْهُمْ فَلَا صَرِيخَ لَهُمْ وَلَا هُمْ يُنقَذُونَ","en":"And if We should will, We could drown them; then no one responding to a cry would there be for them, nor would they be saved","tr":"Wa-in nasha/ nughriqhum fala sareekhalahum wala hum yunqathoon","juz":23,"page":443},{"s":36,"a":44,"key":"36:44","ar":"إِلَّا رَحْمَةً مِّنَّا وَمَتَـٰعًا إِلَىٰ حِينٍ","en":"Except as a mercy from Us and provision for a time.","tr":"Illa rahmatan minnawamataAAan ila heen","juz":23,"page":443},{"s":36,"a":45,"key":"36:45","ar":"وَإِذَا قِيلَ لَهُمُ ٱتَّقُوا۟ مَا بَيْنَ أَيْدِيكُمْ وَمَا خَلْفَكُمْ لَعَلَّكُمْ تُرْحَمُونَ","en":"But when it is said to them, \"Beware of what is before you and what is behind you;1 perhaps you will receive mercy...\"2","tr":"Wa-itha qeela lahumu ittaqoo mabayna aydeekum wama khalfakum laAAallakum turhamoon","juz":23,"page":443},{"s":36,"a":46,"key":"36:46","ar":"وَمَا تَأْتِيهِم مِّنْ ءَايَةٍ مِّنْ ءَايَـٰتِ رَبِّهِمْ إِلَّا كَانُوا۟ عَنْهَا مُعْرِضِينَ","en":"And no sign comes to them from the signs of their Lord except that they are from it turning away.","tr":"Wama ta/teehim min ayatin min ayatirabbihim illa kanoo AAanha muAArideen","juz":23,"page":443},{"s":36,"a":47,"key":"36:47","ar":"وَإِذَا قِيلَ لَهُمْ أَنفِقُوا۟ مِمَّا رَزَقَكُمُ ٱللَّهُ قَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوٓا۟ أَنُطْعِمُ مَن لَّوْ يَشَآءُ ٱللَّهُ أَطْعَمَهُۥٓ إِنْ أَنتُمْ إِلَّا فِى ضَلَـٰلٍ مُّبِينٍ","en":"And when it is said to them, \"Spend from that which Allāh has provided for you,\" those who disbelieve say to those who believe, \"Should we feed one whom, if Allāh had willed, He would have fed? You are not but in clear error.\"","tr":"Wa-itha qeela lahum anfiqoo mimmarazaqakumu Allahu qala allatheena kafaroolillatheena amanoo anutAAimu man law yashaoAllahu atAAamahu in antum illa fee dalalinmubeen","juz":23,"page":443},{"s":36,"a":48,"key":"36:48","ar":"وَيَقُولُونَ مَتَىٰ هَـٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَ","en":"And they say, \"When is this promise, if you should be truthful?\"","tr":"Wayaqooloona mata hathaalwaAAdu in kuntum sadiqeen","juz":23,"page":443},{"s":36,"a":49,"key":"36:49","ar":"مَا يَنظُرُونَ إِلَّا صَيْحَةً وَٰحِدَةً تَأْخُذُهُمْ وَهُمْ يَخِصِّمُونَ","en":"They do not await except one blast1 which will seize them while they are disputing.","tr":"Ma yanthuroona illasayhatan wahidatan ta/khuthuhum wahumyakhissimoon","juz":23,"page":443},{"s":36,"a":50,"key":"36:50","ar":"فَلَا يَسْتَطِيعُونَ تَوْصِيَةً وَلَآ إِلَىٰٓ أَهْلِهِمْ يَرْجِعُونَ","en":"And they will not be able [to give] any instruction, nor to their people can they return.","tr":"Fala yastateeAAoona tawsiyatanwala ila ahlihim yarjiAAoon","juz":23,"page":443},{"s":36,"a":51,"key":"36:51","ar":"وَنُفِخَ فِى ٱلصُّورِ فَإِذَا هُم مِّنَ ٱلْأَجْدَاثِ إِلَىٰ رَبِّهِمْ يَنسِلُونَ","en":"And the Horn will be blown;1 and at once from the graves to their Lord they will hasten.","tr":"Wanufikha fee assoori fa-ithahum mina al-ajdathi ila rabbihim yansiloon","juz":23,"page":443},{"s":36,"a":52,"key":"36:52","ar":"قَالُوا۟ يَـٰوَيْلَنَا مَنۢ بَعَثَنَا مِن مَّرْقَدِنَا ۜ ۗ هَـٰذَا مَا وَعَدَ ٱلرَّحْمَـٰنُ وَصَدَقَ ٱلْمُرْسَلُونَ","en":"They will say, \"O woe to us! Who has raised us up from our sleeping place?\" [The reply will be], \"This is what the Most Merciful had promised, and the messengers told the truth.\"","tr":"Qaloo ya waylana manbaAAathana min marqadina hatha mawaAAada arrahmanu wasadaqaalmursaloon","juz":23,"page":443},{"s":36,"a":53,"key":"36:53","ar":"إِن كَانَتْ إِلَّا صَيْحَةً وَٰحِدَةً فَإِذَا هُمْ جَمِيعٌ لَّدَيْنَا مُحْضَرُونَ","en":"It will not be but one blast, and at once they are all brought present before Us.","tr":"In kanat illa sayhatanwahidatan fa-itha hum jameeAAun ladayna muhdaroon","juz":23,"page":443},{"s":36,"a":54,"key":"36:54","ar":"فَٱلْيَوْمَ لَا تُظْلَمُ نَفْسٌ شَيْـًٔا وَلَا تُجْزَوْنَ إِلَّا مَا كُنتُمْ تَعْمَلُونَ","en":"So today [i.e., the Day of Judgement] no soul will be wronged at all, and you will not be recompensed except for what you used to do.","tr":"Falyawma la tuthlamunafsun shay-an wala tujzawna illa ma kuntumtaAAmaloon","juz":23,"page":443},{"s":36,"a":55,"key":"36:55","ar":"إِنَّ أَصْحَـٰبَ ٱلْجَنَّةِ ٱلْيَوْمَ فِى شُغُلٍ فَـٰكِهُونَ","en":"Indeed the companions of Paradise, that Day, will be amused in [joyful] occupation -","tr":"Inna as-haba aljannati alyawmafee shughulin fakihoon","juz":23,"page":444},{"s":36,"a":56,"key":"36:56","ar":"هُمْ وَأَزْوَٰجُهُمْ فِى ظِلَـٰلٍ عَلَى ٱلْأَرَآئِكِ مُتَّكِـُٔونَ","en":"They and their spouses - in shade, reclining on adorned couches.","tr":"Hum waazwajuhum fee thilalinAAala al-ara-iki muttaki-oon","juz":23,"page":444},{"s":36,"a":57,"key":"36:57","ar":"لَهُمْ فِيهَا فَـٰكِهَةٌ وَلَهُم مَّا يَدَّعُونَ","en":"For them therein is fruit, and for them is whatever they request [or wish]","tr":"Lahum feeha fakihatun walahumma yaddaAAoon","juz":23,"page":444},{"s":36,"a":58,"key":"36:58","ar":"سَلَـٰمٌ قَوْلًا مِّن رَّبٍّ رَّحِيمٍ","en":"[And] \"Peace,\" a word from a Merciful Lord.","tr":"Salamun qawlan min rabbin raheem","juz":23,"page":444},{"s":36,"a":59,"key":"36:59","ar":"وَٱمْتَـٰزُوا۟ ٱلْيَوْمَ أَيُّهَا ٱلْمُجْرِمُونَ","en":"[Then He will say], \"But stand apart today, you criminals.1","tr":"Wamtazoo alyawma ayyuhaalmujrimoon","juz":23,"page":444},{"s":36,"a":60,"key":"36:60","ar":"۞ أَلَمْ أَعْهَدْ إِلَيْكُمْ يَـٰبَنِىٓ ءَادَمَ أَن لَّا تَعْبُدُوا۟ ٱلشَّيْطَـٰنَ ۖ إِنَّهُۥ لَكُمْ عَدُوٌّ مُّبِينٌ","en":"Did I not enjoin upon you, O children of Adam, that you not worship Satan - [for] indeed, he is to you a clear enemy -","tr":"Alam aAAhad ilaykum ya banee adamaan la taAAbudoo ashshaytana innahu lakumAAaduwwun mubeen","juz":23,"page":444},{"s":36,"a":61,"key":"36:61","ar":"وَأَنِ ٱعْبُدُونِى ۚ هَـٰذَا صِرَٰطٌ مُّسْتَقِيمٌ","en":"And that you worship [only] Me? This is a straight path.","tr":"Waani oAAbudoonee hatha siratunmustaqeem","juz":23,"page":444},{"s":36,"a":62,"key":"36:62","ar":"وَلَقَدْ أَضَلَّ مِنكُمْ جِبِلًّا كَثِيرًا ۖ أَفَلَمْ تَكُونُوا۟ تَعْقِلُونَ","en":"And he had already led astray from among you much of creation, so did you not use reason?","tr":"Walaqad adalla minkum jibillankatheeran afalam takoonoo taAAqiloon","juz":23,"page":444},{"s":36,"a":63,"key":"36:63","ar":"هَـٰذِهِۦ جَهَنَّمُ ٱلَّتِى كُنتُمْ تُوعَدُونَ","en":"This is the Hellfire which you were promised.","tr":"Hathihi jahannamu allatee kuntumtooAAadoon","juz":23,"page":444},{"s":36,"a":64,"key":"36:64","ar":"ٱصْلَوْهَا ٱلْيَوْمَ بِمَا كُنتُمْ تَكْفُرُونَ","en":"[Enter to] burn therein today for what you used to deny.\"1","tr":"Islawha alyawma bimakuntum takfuroon","juz":23,"page":444},{"s":36,"a":65,"key":"36:65","ar":"ٱلْيَوْمَ نَخْتِمُ عَلَىٰٓ أَفْوَٰهِهِمْ وَتُكَلِّمُنَآ أَيْدِيهِمْ وَتَشْهَدُ أَرْجُلُهُم بِمَا كَانُوا۟ يَكْسِبُونَ","en":"That Day, We will seal over their mouths, and their hands will speak to Us, and their feet will testify about what they used to earn.","tr":"Alyawma nakhtimu AAala afwahihimwatukallimuna aydeehim watashhadu arjuluhum bima kanooyaksiboon","juz":23,"page":444},{"s":36,"a":66,"key":"36:66","ar":"وَلَوْ نَشَآءُ لَطَمَسْنَا عَلَىٰٓ أَعْيُنِهِمْ فَٱسْتَبَقُوا۟ ٱلصِّرَٰطَ فَأَنَّىٰ يُبْصِرُونَ","en":"And if We willed, We could have obliterated their eyes, and they would race to [find] the path, and how could they see?1","tr":"Walaw nashao latamasnaAAala aAAyunihim fastabaqoo assiratafaanna yubsiroon","juz":23,"page":444},{"s":36,"a":67,"key":"36:67","ar":"وَلَوْ نَشَآءُ لَمَسَخْنَـٰهُمْ عَلَىٰ مَكَانَتِهِمْ فَمَا ٱسْتَطَـٰعُوا۟ مُضِيًّا وَلَا يَرْجِعُونَ","en":"And if We willed, We could have deformed them, [paralyzing them] in their places so they would not be able to proceed, nor could they return.1","tr":"Walaw nashao lamasakhnahumAAala makanatihim fama istataAAoo mudiyyanwala yarjiAAoon","juz":23,"page":444},{"s":36,"a":68,"key":"36:68","ar":"وَمَن نُّعَمِّرْهُ نُنَكِّسْهُ فِى ٱلْخَلْقِ ۖ أَفَلَا يَعْقِلُونَ","en":"And he to whom We grant long life We reverse in creation;1 so will they not understand?","tr":"Waman nuAAammirhu nunakkis-hu fee alkhalqiafala yaAAqiloon","juz":23,"page":444},{"s":36,"a":69,"key":"36:69","ar":"وَمَا عَلَّمْنَـٰهُ ٱلشِّعْرَ وَمَا يَنۢبَغِى لَهُۥٓ ۚ إِنْ هُوَ إِلَّا ذِكْرٌ وَقُرْءَانٌ مُّبِينٌ","en":"And We did not give him [i.e., Prophet Muḥammad (ﷺ)] knowledge of poetry, nor is it befitting for him. It is not but a message and a clear Qur’ān","tr":"Wama AAallamnahu ashshiAArawama yanbaghee lahu in huwa illa thikrunwaqur-anun mubeen","juz":23,"page":444},{"s":36,"a":70,"key":"36:70","ar":"لِّيُنذِرَ مَن كَانَ حَيًّا وَيَحِقَّ ٱلْقَوْلُ عَلَى ٱلْكَـٰفِرِينَ","en":"To warn whoever is alive1 and justify the word [i.e., decree] against the disbelievers.","tr":"Liyunthira man kana hayyanwayahiqqa alqawlu AAala alkafireen","juz":23,"page":444},{"s":36,"a":71,"key":"36:71","ar":"أَوَلَمْ يَرَوْا۟ أَنَّا خَلَقْنَا لَهُم مِّمَّا عَمِلَتْ أَيْدِينَآ أَنْعَـٰمًا فَهُمْ لَهَا مَـٰلِكُونَ","en":"Do they not see that We have created for them from what Our hands1 have made, grazing livestock, and [then] they are their owners?","tr":"Awa lam yaraw anna khalaqnalahum mimma AAamilat aydeena anAAaman fahumlaha malikoon","juz":23,"page":445},{"s":36,"a":72,"key":"36:72","ar":"وَذَلَّلْنَـٰهَا لَهُمْ فَمِنْهَا رَكُوبُهُمْ وَمِنْهَا يَأْكُلُونَ","en":"And We have tamed them for them, so some of them they ride, and some of them they eat.","tr":"Wathallalnaha lahumfaminha rakoobuhum waminha ya/kuloon","juz":23,"page":445},{"s":36,"a":73,"key":"36:73","ar":"وَلَهُمْ فِيهَا مَنَـٰفِعُ وَمَشَارِبُ ۖ أَفَلَا يَشْكُرُونَ","en":"And for them therein are [other] benefits and drinks, so will they not be grateful?","tr":"Walahum feeha manafiAAu wamasharibuafala yashkuroon","juz":23,"page":445},{"s":36,"a":74,"key":"36:74","ar":"وَٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ ءَالِهَةً لَّعَلَّهُمْ يُنصَرُونَ","en":"But they have taken besides Allāh [false] deities that perhaps they would be helped.","tr":"Wattakhathoo min dooni Allahialihatan laAAallahum yunsaroon","juz":23,"page":445},{"s":36,"a":75,"key":"36:75","ar":"لَا يَسْتَطِيعُونَ نَصْرَهُمْ وَهُمْ لَهُمْ جُندٌ مُّحْضَرُونَ","en":"They are not able to help them, and they [themselves] are for them soldiers in attendance.1","tr":"La yastateeAAoona nasrahumwahum lahum jundun muhdaroon","juz":23,"page":445},{"s":36,"a":76,"key":"36:76","ar":"فَلَا يَحْزُنكَ قَوْلُهُمْ ۘ إِنَّا نَعْلَمُ مَا يُسِرُّونَ وَمَا يُعْلِنُونَ","en":"So let not their speech grieve you. Indeed, We know what they conceal and what they declare.","tr":"Fala yahzunka qawluhum innanaAAlamu ma yusirroona wama yuAAlinoon","juz":23,"page":445},{"s":36,"a":77,"key":"36:77","ar":"أَوَلَمْ يَرَ ٱلْإِنسَـٰنُ أَنَّا خَلَقْنَـٰهُ مِن نُّطْفَةٍ فَإِذَا هُوَ خَصِيمٌ مُّبِينٌ","en":"Does man not consider that We created him from a [mere] sperm-drop - then at once1 he is a clear adversary?","tr":"Awa lam yara al-insanu annakhalaqnahu min nutfatin fa-itha huwa khaseemunmubeen","juz":23,"page":445},{"s":36,"a":78,"key":"36:78","ar":"وَضَرَبَ لَنَا مَثَلًا وَنَسِىَ خَلْقَهُۥ ۖ قَالَ مَن يُحْىِ ٱلْعِظَـٰمَ وَهِىَ رَمِيمٌ","en":"And he presents for Us an example1 and forgets his [own] creation. He says, \"Who will give life to bones while they are disintegrated?\"","tr":"Wadaraba lana mathalanwanasiya khalqahu qala man yuhyee alAAithamawahiya rameem","juz":23,"page":445},{"s":36,"a":79,"key":"36:79","ar":"قُلْ يُحْيِيهَا ٱلَّذِىٓ أَنشَأَهَآ أَوَّلَ مَرَّةٍ ۖ وَهُوَ بِكُلِّ خَلْقٍ عَلِيمٌ","en":"Say, \"He will give them life who produced them the first time; and He is, of all creation, Knowing.\"","tr":"Qul yuhyeeha allatheeanshaaha awwala marratin wahuwa bikulli khalqin AAaleem","juz":23,"page":445},{"s":36,"a":80,"key":"36:80","ar":"ٱلَّذِى جَعَلَ لَكُم مِّنَ ٱلشَّجَرِ ٱلْأَخْضَرِ نَارًا فَإِذَآ أَنتُم مِّنْهُ تُوقِدُونَ","en":"[It is] He who made for you from the green tree, fire, and then from it you ignite.","tr":"Allathee jaAAala lakum mina ashshajarial-akhdari naran fa-itha antum minhutooqidoon","juz":23,"page":445},{"s":36,"a":81,"key":"36:81","ar":"أَوَلَيْسَ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ بِقَـٰدِرٍ عَلَىٰٓ أَن يَخْلُقَ مِثْلَهُم ۚ بَلَىٰ وَهُوَ ٱلْخَلَّـٰقُ ٱلْعَلِيمُ","en":"Is not He who created the heavens and the earth Able to create the likes of them? Yes, [it is so]; and He is the Knowing Creator.","tr":"Awa laysa allathee khalaqa assamawatiwal-arda biqadirin AAala an yakhluqamithlahum bala wahuwa alkhallaqu alAAaleem","juz":23,"page":445},{"s":36,"a":82,"key":"36:82","ar":"إِنَّمَآ أَمْرُهُۥٓ إِذَآ أَرَادَ شَيْـًٔا أَن يَقُولَ لَهُۥ كُن فَيَكُونُ","en":"His command is only when He intends a thing that He says to it, \"Be,\" and it is.","tr":"Innama amruhu itha aradashay-an an yaqoola lahu kun fayakoon","juz":23,"page":445},{"s":36,"a":83,"key":"36:83","ar":"فَسُبْحَـٰنَ ٱلَّذِى بِيَدِهِۦ مَلَكُوتُ كُلِّ شَىْءٍ وَإِلَيْهِ تُرْجَعُونَ","en":"So exalted is He in whose hand is the realm of all things, and to Him you will be returned.","tr":"Fasubhana allathee biyadihimalakootu kulli shay-in wa-ilayhi turjaAAoon","juz":23,"page":445},{"s":37,"a":1,"key":"37:1","ar":" وَٱلصَّـٰٓفَّـٰتِ صَفًّا","en":"By those [angels] lined up in rows","tr":"Wassaffati saffa","juz":23,"page":446},{"s":37,"a":2,"key":"37:2","ar":"فَٱلزَّٰجِرَٰتِ زَجْرًا","en":"And those who drive [the clouds]","tr":"Fazzajirati zajra","juz":23,"page":446},{"s":37,"a":3,"key":"37:3","ar":"فَٱلتَّـٰلِيَـٰتِ ذِكْرًا","en":"And those who recite the message,1","tr":"Fattaliyati thikra","juz":23,"page":446},{"s":37,"a":4,"key":"37:4","ar":"إِنَّ إِلَـٰهَكُمْ لَوَٰحِدٌ","en":"Indeed, your God is One,","tr":"Inna ilahakum lawahid","juz":23,"page":446},{"s":37,"a":5,"key":"37:5","ar":"رَّبُّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا وَرَبُّ ٱلْمَشَـٰرِقِ","en":"Lord of the heavens and the earth and that between them and Lord of the sunrises.1","tr":"Rabbu assamawati wal-ardiwama baynahuma warabbu almashariq","juz":23,"page":446},{"s":37,"a":6,"key":"37:6","ar":"إِنَّا زَيَّنَّا ٱلسَّمَآءَ ٱلدُّنْيَا بِزِينَةٍ ٱلْكَوَاكِبِ","en":"Indeed, We have adorned the nearest heaven with an adornment of stars","tr":"Inna zayyanna assamaaaddunya bizeenatin alkawakib","juz":23,"page":446},{"s":37,"a":7,"key":"37:7","ar":"وَحِفْظًا مِّن كُلِّ شَيْطَـٰنٍ مَّارِدٍ","en":"And as protection against every rebellious devil","tr":"Wahifthan min kulli shaytaninmarid","juz":23,"page":446},{"s":37,"a":8,"key":"37:8","ar":"لَّا يَسَّمَّعُونَ إِلَى ٱلْمَلَإِ ٱلْأَعْلَىٰ وَيُقْذَفُونَ مِن كُلِّ جَانِبٍ","en":"[So] they may not listen to the exalted assembly [of angels] and are pelted from every side,1","tr":"La yassammaAAoona ila almala-ial-aAAla wayuqthafoona min kulli janib","juz":23,"page":446},{"s":37,"a":9,"key":"37:9","ar":"دُحُورًا ۖ وَلَهُمْ عَذَابٌ وَاصِبٌ","en":"Repelled; and for them is a constant punishment,","tr":"Duhooran walahum AAathabun wasib","juz":23,"page":446},{"s":37,"a":10,"key":"37:10","ar":"إِلَّا مَنْ خَطِفَ ٱلْخَطْفَةَ فَأَتْبَعَهُۥ شِهَابٌ ثَاقِبٌ","en":"Except one who snatches [some words] by theft, but they are pursued by a burning flame, piercing [in brightness].","tr":"Illa man khatifa alkhatfatafaatbaAAahu shihabun thaqib","juz":23,"page":446},{"s":37,"a":11,"key":"37:11","ar":"فَٱسْتَفْتِهِمْ أَهُمْ أَشَدُّ خَلْقًا أَم مَّنْ خَلَقْنَآ ۚ إِنَّا خَلَقْنَـٰهُم مِّن طِينٍ لَّازِبٍۭ","en":"Then inquire of them, [O Muḥammad], \"Are they a stronger [or more difficult] creation or those [others] We have created?\" Indeed, We created them [i.e., men] from sticky clay.","tr":"Fastaftihim ahum ashaddu khalqan amman khalaqna inna khalaqnahum min teeninlazib","juz":23,"page":446},{"s":37,"a":12,"key":"37:12","ar":"بَلْ عَجِبْتَ وَيَسْخَرُونَ","en":"But you wonder, while they mock,","tr":"Bal AAajibta wayaskharoon","juz":23,"page":446},{"s":37,"a":13,"key":"37:13","ar":"وَإِذَا ذُكِّرُوا۟ لَا يَذْكُرُونَ","en":"And when they are reminded, they remember not.","tr":"Wa-itha thukkiroo la yathkuroon","juz":23,"page":446},{"s":37,"a":14,"key":"37:14","ar":"وَإِذَا رَأَوْا۟ ءَايَةً يَسْتَسْخِرُونَ","en":"And when they see a sign, they ridicule.","tr":"Wa-itha raaw ayatanyastaskhiroon","juz":23,"page":446},{"s":37,"a":15,"key":"37:15","ar":"وَقَالُوٓا۟ إِنْ هَـٰذَآ إِلَّا سِحْرٌ مُّبِينٌ","en":"And say, \"This is not but obvious magic.","tr":"Waqaloo in hatha illasihrun mubeen","juz":23,"page":446},{"s":37,"a":16,"key":"37:16","ar":"أَءِذَا مِتْنَا وَكُنَّا تُرَابًا وَعِظَـٰمًا أَءِنَّا لَمَبْعُوثُونَ","en":"When we have died and become dust and bones, are we indeed to be resurrected?","tr":"A-itha mitna wakunnaturaban waAAithaman a-innalamabAAoothoon","juz":23,"page":446},{"s":37,"a":17,"key":"37:17","ar":"أَوَءَابَآؤُنَا ٱلْأَوَّلُونَ","en":"And our forefathers [as well]?\"","tr":"Awa abaona al-awwaloon","juz":23,"page":446},{"s":37,"a":18,"key":"37:18","ar":"قُلْ نَعَمْ وَأَنتُمْ دَٰخِرُونَ","en":"Say, \"Yes, and you will be [rendered] contemptible.\"","tr":"Qul naAAam waantum dakhiroon","juz":23,"page":446},{"s":37,"a":19,"key":"37:19","ar":"فَإِنَّمَا هِىَ زَجْرَةٌ وَٰحِدَةٌ فَإِذَا هُمْ يَنظُرُونَ","en":"It will be only one shout, and at once they will be observing.","tr":"Fa-innama hiya zajratun wahidatunfa-itha hum yanthuroon","juz":23,"page":446},{"s":37,"a":20,"key":"37:20","ar":"وَقَالُوا۟ يَـٰوَيْلَنَا هَـٰذَا يَوْمُ ٱلدِّينِ","en":"They will say, \"O woe to us! This is the Day of Recompense.\"","tr":"Waqaloo ya waylana hathayawmu addeen","juz":23,"page":446},{"s":37,"a":21,"key":"37:21","ar":"هَـٰذَا يَوْمُ ٱلْفَصْلِ ٱلَّذِى كُنتُم بِهِۦ تُكَذِّبُونَ","en":"[They will be told], \"This is the Day of Judgement which you used to deny.\"","tr":"Hatha yawmu alfasli allatheekuntum bihi tukaththiboon","juz":23,"page":446},{"s":37,"a":22,"key":"37:22","ar":"۞ ٱحْشُرُوا۟ ٱلَّذِينَ ظَلَمُوا۟ وَأَزْوَٰجَهُمْ وَمَا كَانُوا۟ يَعْبُدُونَ","en":"[The angels will be ordered], \"Gather those who committed wrong, their kinds,1 and what they used to worship","tr":"Ohshuroo allatheena thalamoowaazwajahum wama kanoo yaAAbudoon","juz":23,"page":446},{"s":37,"a":23,"key":"37:23","ar":"مِن دُونِ ٱللَّهِ فَٱهْدُوهُمْ إِلَىٰ صِرَٰطِ ٱلْجَحِيمِ","en":"Other than Allāh, and guide them to the path of Hellfire","tr":"Min dooni Allahi fahdoohum ilasirati aljaheem","juz":23,"page":446},{"s":37,"a":24,"key":"37:24","ar":"وَقِفُوهُمْ ۖ إِنَّهُم مَّسْـُٔولُونَ","en":"And stop them; indeed, they are to be questioned.\"","tr":"Waqifoohum innahum masooloon","juz":23,"page":446},{"s":37,"a":25,"key":"37:25","ar":"مَا لَكُمْ لَا تَنَاصَرُونَ","en":"[They will be asked], \"What is [wrong] with you? Why do you not help each other?\"","tr":"Ma lakum la tanasaroon","juz":23,"page":447},{"s":37,"a":26,"key":"37:26","ar":"بَلْ هُمُ ٱلْيَوْمَ مُسْتَسْلِمُونَ","en":"But they, that Day, are in surrender.","tr":"Bal humu alyawma mustaslimoon","juz":23,"page":447},{"s":37,"a":27,"key":"37:27","ar":"وَأَقْبَلَ بَعْضُهُمْ عَلَىٰ بَعْضٍ يَتَسَآءَلُونَ","en":"And they will approach one another asking [i.e., blaming] each other.","tr":"Waaqbala baAAduhum AAala baAAdinyatasaaloon","juz":23,"page":447},{"s":37,"a":28,"key":"37:28","ar":"قَالُوٓا۟ إِنَّكُمْ كُنتُمْ تَأْتُونَنَا عَنِ ٱلْيَمِينِ","en":"They will say, \"Indeed, you used to come at us from the right.\"1","tr":"Qaloo innakum kuntum ta/toonanaAAani alyameen","juz":23,"page":447},{"s":37,"a":29,"key":"37:29","ar":"قَالُوا۟ بَل لَّمْ تَكُونُوا۟ مُؤْمِنِينَ","en":"They [i.e., the oppressors] will say, \"Rather, you [yourselves] were not believers,","tr":"Qaloo bal lam takoonoo mu/mineen","juz":23,"page":447},{"s":37,"a":30,"key":"37:30","ar":"وَمَا كَانَ لَنَا عَلَيْكُم مِّن سُلْطَـٰنٍۭ ۖ بَلْ كُنتُمْ قَوْمًا طَـٰغِينَ","en":"And we had over you no authority, but you were a transgressing people.","tr":"Wama kana lanaAAalaykum min sultanin bal kuntum qawman tagheen","juz":23,"page":447},{"s":37,"a":31,"key":"37:31","ar":"فَحَقَّ عَلَيْنَا قَوْلُ رَبِّنَآ ۖ إِنَّا لَذَآئِقُونَ","en":"So the word [i.e., decree] of our Lord has come into effect upon us; indeed, we will taste [punishment].","tr":"Fahaqqa AAalayna qawlu rabbinainna latha-iqoon","juz":23,"page":447},{"s":37,"a":32,"key":"37:32","ar":"فَأَغْوَيْنَـٰكُمْ إِنَّا كُنَّا غَـٰوِينَ","en":"And we led you to deviation; indeed, we were deviators.\"","tr":"Faaghwaynakum inna kunnaghaween","juz":23,"page":447},{"s":37,"a":33,"key":"37:33","ar":"فَإِنَّهُمْ يَوْمَئِذٍ فِى ٱلْعَذَابِ مُشْتَرِكُونَ","en":"So indeed they, that Day, will be sharing in the punishment.","tr":"Fa-innahum yawma-ithin fee alAAathabimushtarikoon","juz":23,"page":447},{"s":37,"a":34,"key":"37:34","ar":"إِنَّا كَذَٰلِكَ نَفْعَلُ بِٱلْمُجْرِمِينَ","en":"Indeed, that is how We deal with the criminals.","tr":"Inna kathalika nafAAalu bilmujrimeen","juz":23,"page":447},{"s":37,"a":35,"key":"37:35","ar":"إِنَّهُمْ كَانُوٓا۟ إِذَا قِيلَ لَهُمْ لَآ إِلَـٰهَ إِلَّا ٱللَّهُ يَسْتَكْبِرُونَ","en":"Indeed they, when it was said to them, \"There is no deity but Allāh,\" were arrogant","tr":"Innahum kanoo itha qeela lahumla ilaha illa Allahu yastakbiroon","juz":23,"page":447},{"s":37,"a":36,"key":"37:36","ar":"وَيَقُولُونَ أَئِنَّا لَتَارِكُوٓا۟ ءَالِهَتِنَا لِشَاعِرٍ مَّجْنُونٍۭ","en":"And were saying, \"Are we to leave our gods for a mad poet?\"","tr":"Wayaqooloona a-inna latarikoo alihatinalishaAAirin majnoon","juz":23,"page":447},{"s":37,"a":37,"key":"37:37","ar":"بَلْ جَآءَ بِٱلْحَقِّ وَصَدَّقَ ٱلْمُرْسَلِينَ","en":"Rather, he [i.e., the Prophet (ﷺ)] has come with the truth and confirmed the [previous] messengers.","tr":"Bal jaa bilhaqqi wasaddaqaalmursaleen","juz":23,"page":447},{"s":37,"a":38,"key":"37:38","ar":"إِنَّكُمْ لَذَآئِقُوا۟ ٱلْعَذَابِ ٱلْأَلِيمِ","en":"Indeed, you [disbelievers] will be tasters of the painful punishment,","tr":"Innakum latha-iqoo alAAathabial-aleem","juz":23,"page":447},{"s":37,"a":39,"key":"37:39","ar":"وَمَا تُجْزَوْنَ إِلَّا مَا كُنتُمْ تَعْمَلُونَ","en":"And you will not be recompensed except for what you used to do -","tr":"Wama tujzawna illa makuntum taAAmaloon","juz":23,"page":447},{"s":37,"a":40,"key":"37:40","ar":"إِلَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ","en":"But not the chosen servants of Allāh.","tr":"Illa AAibada Allahialmukhlaseen","juz":23,"page":447},{"s":37,"a":41,"key":"37:41","ar":"أُو۟لَـٰٓئِكَ لَهُمْ رِزْقٌ مَّعْلُومٌ","en":"Those will have a provision determined -","tr":"Ola-ika lahum rizqun maAAloom","juz":23,"page":447},{"s":37,"a":42,"key":"37:42","ar":"فَوَٰكِهُ ۖ وَهُم مُّكْرَمُونَ","en":"Fruits;1 and they will be honored","tr":"Fawakihu wahum mukramoon","juz":23,"page":447},{"s":37,"a":43,"key":"37:43","ar":"فِى جَنَّـٰتِ ٱلنَّعِيمِ","en":"In gardens of pleasure","tr":"Fee jannati annaAAeem","juz":23,"page":447},{"s":37,"a":44,"key":"37:44","ar":"عَلَىٰ سُرُرٍ مُّتَقَـٰبِلِينَ","en":"On thrones facing one another.","tr":"AAala sururin mutaqabileen","juz":23,"page":447},{"s":37,"a":45,"key":"37:45","ar":"يُطَافُ عَلَيْهِم بِكَأْسٍ مِّن مَّعِينٍۭ","en":"There will be circulated among them a cup [of wine] from a flowing spring,","tr":"Yutafu AAalayhim bika/sin min maAAeen","juz":23,"page":447},{"s":37,"a":46,"key":"37:46","ar":"بَيْضَآءَ لَذَّةٍ لِّلشَّـٰرِبِينَ","en":"White and delicious to the drinkers;","tr":"Baydaa laththatin lishsharibeen","juz":23,"page":447},{"s":37,"a":47,"key":"37:47","ar":"لَا فِيهَا غَوْلٌ وَلَا هُمْ عَنْهَا يُنزَفُونَ","en":"No bad effect is there in it, nor from it will they be intoxicated.","tr":"La feeha ghawlun walahum AAanha yunzafoon","juz":23,"page":447},{"s":37,"a":48,"key":"37:48","ar":"وَعِندَهُمْ قَـٰصِرَٰتُ ٱلطَّرْفِ عِينٌ","en":"And with them will be women limiting [their] glances,1 with large, [beautiful] eyes,","tr":"WaAAindahum qasiratu attarfiAAeen","juz":23,"page":447},{"s":37,"a":49,"key":"37:49","ar":"كَأَنَّهُنَّ بَيْضٌ مَّكْنُونٌ","en":"As if they were [delicate] eggs, well-protected.","tr":"Kaannahunna baydun maknoon","juz":23,"page":447},{"s":37,"a":50,"key":"37:50","ar":"فَأَقْبَلَ بَعْضُهُمْ عَلَىٰ بَعْضٍ يَتَسَآءَلُونَ","en":"And they will approach one another, inquiring of each other.","tr":"Faaqbala baAAduhum AAala baAAdinyatasaaloon","juz":23,"page":447},{"s":37,"a":51,"key":"37:51","ar":"قَالَ قَآئِلٌ مِّنْهُمْ إِنِّى كَانَ لِى قَرِينٌ","en":"A speaker among them will say, \"Indeed, I had a companion [on earth].","tr":"Qala qa-ilun minhum innee kanalee qareen","juz":23,"page":447},{"s":37,"a":52,"key":"37:52","ar":"يَقُولُ أَءِنَّكَ لَمِنَ ٱلْمُصَدِّقِينَ","en":"Who would say, 'Are you indeed of those who believe","tr":"Yaqoolu a-innaka lamina almusaddiqeen","juz":23,"page":448},{"s":37,"a":53,"key":"37:53","ar":"أَءِذَا مِتْنَا وَكُنَّا تُرَابًا وَعِظَـٰمًا أَءِنَّا لَمَدِينُونَ","en":"That when we have died and become dust and bones, we will indeed be recompensed?'\"","tr":"A-itha mitna wakunnaturaban waAAithaman a-innalamadeenoon","juz":23,"page":448},{"s":37,"a":54,"key":"37:54","ar":"قَالَ هَلْ أَنتُم مُّطَّلِعُونَ","en":"He will say,1 \"Would you [care to] look?\"","tr":"Qala hal antum muttaliAAoon","juz":23,"page":448},{"s":37,"a":55,"key":"37:55","ar":"فَٱطَّلَعَ فَرَءَاهُ فِى سَوَآءِ ٱلْجَحِيمِ","en":"And he will look and see him1 in the midst of the Hellfire.","tr":"FattalaAAa faraahu feesawa-i aljaheem","juz":23,"page":448},{"s":37,"a":56,"key":"37:56","ar":"قَالَ تَٱللَّهِ إِن كِدتَّ لَتُرْدِينِ","en":"He will say, \"By Allāh, you almost ruined me.","tr":"Qala tallahi in kidtalaturdeen","juz":23,"page":448},{"s":37,"a":57,"key":"37:57","ar":"وَلَوْلَا نِعْمَةُ رَبِّى لَكُنتُ مِنَ ٱلْمُحْضَرِينَ","en":"If not for the favor of my Lord, I would have been of those brought in [to Hell].","tr":"Walawla niAAmatu rabbee lakuntu minaalmuhdareen","juz":23,"page":448},{"s":37,"a":58,"key":"37:58","ar":"أَفَمَا نَحْنُ بِمَيِّتِينَ","en":"Then, are we not to die","tr":"Afama nahnu bimayyiteen","juz":23,"page":448},{"s":37,"a":59,"key":"37:59","ar":"إِلَّا مَوْتَتَنَا ٱلْأُولَىٰ وَمَا نَحْنُ بِمُعَذَّبِينَ","en":"Except for our first death, and we will not be punished?\"","tr":"Illa mawtatana al-oolawama nahnu bimuAAaththabeen","juz":23,"page":448},{"s":37,"a":60,"key":"37:60","ar":"إِنَّ هَـٰذَا لَهُوَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"Indeed, this is the great attainment.","tr":"Inna hatha lahuwa alfawzu alAAatheem","juz":23,"page":448},{"s":37,"a":61,"key":"37:61","ar":"لِمِثْلِ هَـٰذَا فَلْيَعْمَلِ ٱلْعَـٰمِلُونَ","en":"For the like of this let the workers [on earth] work.","tr":"Limithli hatha falyaAAmali alAAamiloon","juz":23,"page":448},{"s":37,"a":62,"key":"37:62","ar":"أَذَٰلِكَ خَيْرٌ نُّزُلًا أَمْ شَجَرَةُ ٱلزَّقُّومِ","en":"Is that [i.e., Paradise] a better accommodation or the tree of zaqqūm?","tr":"Athalika khayrun nuzulan am shajaratuazzaqqoom","juz":23,"page":448},{"s":37,"a":63,"key":"37:63","ar":"إِنَّا جَعَلْنَـٰهَا فِتْنَةً لِّلظَّـٰلِمِينَ","en":"Indeed, We have made it a torment for the wrongdoers.","tr":"Inna jaAAalnahafitnatan liththalimeen","juz":23,"page":448},{"s":37,"a":64,"key":"37:64","ar":"إِنَّهَا شَجَرَةٌ تَخْرُجُ فِىٓ أَصْلِ ٱلْجَحِيمِ","en":"Indeed, it is a tree issuing from the bottom of the Hellfire,","tr":"Innaha shajaratun takhruju fee aslialjaheem","juz":23,"page":448},{"s":37,"a":65,"key":"37:65","ar":"طَلْعُهَا كَأَنَّهُۥ رُءُوسُ ٱلشَّيَـٰطِينِ","en":"Its emerging fruit as if it was heads of the devils.","tr":"TalAAuha kaannahu ruoosu ashshayateen","juz":23,"page":448},{"s":37,"a":66,"key":"37:66","ar":"فَإِنَّهُمْ لَـَٔاكِلُونَ مِنْهَا فَمَالِـُٔونَ مِنْهَا ٱلْبُطُونَ","en":"And indeed, they will eat from it and fill with it their bellies.","tr":"Fa-innahum laakiloona minhafamali-oona minha albutoon","juz":23,"page":448},{"s":37,"a":67,"key":"37:67","ar":"ثُمَّ إِنَّ لَهُمْ عَلَيْهَا لَشَوْبًا مِّنْ حَمِيمٍ","en":"Then indeed, they will have after it a mixture of scalding water.","tr":"Thumma inna lahum AAalayha lashawbanmin hameem","juz":23,"page":448},{"s":37,"a":68,"key":"37:68","ar":"ثُمَّ إِنَّ مَرْجِعَهُمْ لَإِلَى ٱلْجَحِيمِ","en":"Then indeed, their return will be to the Hellfire.","tr":"Thumma inna marjiAAahum la-ila aljaheem","juz":23,"page":448},{"s":37,"a":69,"key":"37:69","ar":"إِنَّهُمْ أَلْفَوْا۟ ءَابَآءَهُمْ ضَآلِّينَ","en":"Indeed they found their fathers astray.","tr":"Innahum alfaw abaahum dalleen","juz":23,"page":448},{"s":37,"a":70,"key":"37:70","ar":"فَهُمْ عَلَىٰٓ ءَاثَـٰرِهِمْ يُهْرَعُونَ","en":"So they hastened [to follow] in their footsteps.","tr":"Fahum AAala atharihimyuhraAAoon","juz":23,"page":448},{"s":37,"a":71,"key":"37:71","ar":"وَلَقَدْ ضَلَّ قَبْلَهُمْ أَكْثَرُ ٱلْأَوَّلِينَ","en":"And there had already strayed before them most of the former peoples,","tr":"Walaqad dalla qablahum aktharual-awwaleen","juz":23,"page":448},{"s":37,"a":72,"key":"37:72","ar":"وَلَقَدْ أَرْسَلْنَا فِيهِم مُّنذِرِينَ","en":"And We had already sent among them warners.","tr":"Walaqad arsalna feehim munthireen","juz":23,"page":448},{"s":37,"a":73,"key":"37:73","ar":"فَٱنظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُنذَرِينَ","en":"Then look how was the end of those who were warned -","tr":"Fanthur kayfa kanaAAaqibatu almunthareen","juz":23,"page":448},{"s":37,"a":74,"key":"37:74","ar":"إِلَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ","en":"But not the chosen servants of Allāh.","tr":"Illa AAibada Allahialmukhlaseen","juz":23,"page":448},{"s":37,"a":75,"key":"37:75","ar":"وَلَقَدْ نَادَىٰنَا نُوحٌ فَلَنِعْمَ ٱلْمُجِيبُونَ","en":"And Noah had certainly called Us, and [We are] the best of responders.","tr":"Walaqad nadana noohunfalaniAAma almujeeboon","juz":23,"page":448},{"s":37,"a":76,"key":"37:76","ar":"وَنَجَّيْنَـٰهُ وَأَهْلَهُۥ مِنَ ٱلْكَرْبِ ٱلْعَظِيمِ","en":"And We saved him and his family from the great affliction.","tr":"Wanajjaynahu waahlahu mina alkarbialAAatheem","juz":23,"page":448},{"s":37,"a":77,"key":"37:77","ar":"وَجَعَلْنَا ذُرِّيَّتَهُۥ هُمُ ٱلْبَاقِينَ","en":"And We made his descendants those remaining [on the earth]","tr":"WajaAAalna thurriyyatahu humualbaqeen","juz":23,"page":449},{"s":37,"a":78,"key":"37:78","ar":"وَتَرَكْنَا عَلَيْهِ فِى ٱلْـَٔاخِرِينَ","en":"And left for him [favorable mention] among later generations:","tr":"Watarakna AAalayhi fee al-akhireen","juz":23,"page":449},{"s":37,"a":79,"key":"37:79","ar":"سَلَـٰمٌ عَلَىٰ نُوحٍ فِى ٱلْعَـٰلَمِينَ","en":"\"Peace upon Noah among the worlds.\"","tr":"Salamun AAala noohinfee alAAalameen","juz":23,"page":449},{"s":37,"a":80,"key":"37:80","ar":"إِنَّا كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ","en":"Indeed, We thus reward the doers of good.","tr":"Inna kathalika najzee almuhsineen","juz":23,"page":449},{"s":37,"a":81,"key":"37:81","ar":"إِنَّهُۥ مِنْ عِبَادِنَا ٱلْمُؤْمِنِينَ","en":"Indeed, he was of Our believing servants.","tr":"Innahu min AAibadinaalmu/mineen","juz":23,"page":449},{"s":37,"a":82,"key":"37:82","ar":"ثُمَّ أَغْرَقْنَا ٱلْـَٔاخَرِينَ","en":"Then We drowned the others [i.e., disbelievers].","tr":"Thumma aghraqna al-akhareen","juz":23,"page":449},{"s":37,"a":83,"key":"37:83","ar":"۞ وَإِنَّ مِن شِيعَتِهِۦ لَإِبْرَٰهِيمَ","en":"And indeed, among his kind was Abraham,","tr":"Wa-inna min sheeAAatihi la-ibraheem","juz":23,"page":449},{"s":37,"a":84,"key":"37:84","ar":"إِذْ جَآءَ رَبَّهُۥ بِقَلْبٍ سَلِيمٍ","en":"When he came to his Lord with a sound heart","tr":"Ith jaa rabbahu biqalbinsaleem","juz":23,"page":449},{"s":37,"a":85,"key":"37:85","ar":"إِذْ قَالَ لِأَبِيهِ وَقَوْمِهِۦ مَاذَا تَعْبُدُونَ","en":"[And] when he said to his father and his people, \"What do you worship?","tr":"Ith qala li-abeehi waqawmihi mathataAAbudoon","juz":23,"page":449},{"s":37,"a":86,"key":"37:86","ar":"أَئِفْكًا ءَالِهَةً دُونَ ٱللَّهِ تُرِيدُونَ","en":"Is it falsehood [as] gods other than Allāh you desire?","tr":"A-ifkan alihatan doona Allahitureedoon","juz":23,"page":449},{"s":37,"a":87,"key":"37:87","ar":"فَمَا ظَنُّكُم بِرَبِّ ٱلْعَـٰلَمِينَ","en":"Then what is your thought about the Lord of the worlds?\"","tr":"Fama thannukum birabbialAAalameen","juz":23,"page":449},{"s":37,"a":88,"key":"37:88","ar":"فَنَظَرَ نَظْرَةً فِى ٱلنُّجُومِ","en":"And he cast a look at the stars.","tr":"Fanathara nathratanfee annujoom","juz":23,"page":449},{"s":37,"a":89,"key":"37:89","ar":"فَقَالَ إِنِّى سَقِيمٌ","en":"And said, \"Indeed, I am [about to be] ill.\"","tr":"Faqala innee saqeem","juz":23,"page":449},{"s":37,"a":90,"key":"37:90","ar":"فَتَوَلَّوْا۟ عَنْهُ مُدْبِرِينَ","en":"So they turned away from him, departing.","tr":"Fatawallaw AAanhu mudbireen","juz":23,"page":449},{"s":37,"a":91,"key":"37:91","ar":"فَرَاغَ إِلَىٰٓ ءَالِهَتِهِمْ فَقَالَ أَلَا تَأْكُلُونَ","en":"Then he turned to their gods and said, \"Do you not eat?1","tr":"Faragha ila alihatihimfaqala ala ta/kuloon","juz":23,"page":449},{"s":37,"a":92,"key":"37:92","ar":"مَا لَكُمْ لَا تَنطِقُونَ","en":"What is [wrong] with you that you do not speak?\".","tr":"Ma lakum la tantiqoon","juz":23,"page":449},{"s":37,"a":93,"key":"37:93","ar":"فَرَاغَ عَلَيْهِمْ ضَرْبًۢا بِٱلْيَمِينِ","en":"And he turned upon them a blow with [his] right hand.","tr":"Faragha AAalayhim darban bilyameen","juz":23,"page":449},{"s":37,"a":94,"key":"37:94","ar":"فَأَقْبَلُوٓا۟ إِلَيْهِ يَزِفُّونَ","en":"Then they [i.e., the people] came toward him, hastening.","tr":"Faaqbaloo ilayhi yaziffoon","juz":23,"page":449},{"s":37,"a":95,"key":"37:95","ar":"قَالَ أَتَعْبُدُونَ مَا تَنْحِتُونَ","en":"He said, \"Do you worship that which you [yourselves] carve,","tr":"Qala ataAAbudoona ma tanhitoon","juz":23,"page":449},{"s":37,"a":96,"key":"37:96","ar":"وَٱللَّهُ خَلَقَكُمْ وَمَا تَعْمَلُونَ","en":"While Allāh created you and that which you do?\"","tr":"Wallahu khalaqakum wamataAAmaloon","juz":23,"page":449},{"s":37,"a":97,"key":"37:97","ar":"قَالُوا۟ ٱبْنُوا۟ لَهُۥ بُنْيَـٰنًا فَأَلْقُوهُ فِى ٱلْجَحِيمِ","en":"They said, \"Construct for him a structure [i.e., furnace] and throw him into the burning fire.\"","tr":"Qaloo ibnoo lahu bunyananfaalqoohu fee aljaheem","juz":23,"page":449},{"s":37,"a":98,"key":"37:98","ar":"فَأَرَادُوا۟ بِهِۦ كَيْدًا فَجَعَلْنَـٰهُمُ ٱلْأَسْفَلِينَ","en":"And they intended for him a plan [i.e., harm], but We made them the most debased.","tr":"Faaradoo bihi kaydan fajaAAalnahumual-asfaleen","juz":23,"page":449},{"s":37,"a":99,"key":"37:99","ar":"وَقَالَ إِنِّى ذَاهِبٌ إِلَىٰ رَبِّى سَيَهْدِينِ","en":"And [then] he said, \"Indeed, I will go to [where I am ordered by] my Lord; He will guide me.","tr":"Waqala innee thahibun ilarabbee sayahdeen","juz":23,"page":449},{"s":37,"a":100,"key":"37:100","ar":"رَبِّ هَبْ لِى مِنَ ٱلصَّـٰلِحِينَ","en":"My Lord, grant me [a child] from among the righteous.\"","tr":"Rabbi hablee mina assaliheen","juz":23,"page":449},{"s":37,"a":101,"key":"37:101","ar":"فَبَشَّرْنَـٰهُ بِغُلَـٰمٍ حَلِيمٍ","en":"So We gave him good tidings of a forbearing boy.","tr":"Fabashsharnahu bighulamin haleem","juz":23,"page":449},{"s":37,"a":102,"key":"37:102","ar":"فَلَمَّا بَلَغَ مَعَهُ ٱلسَّعْىَ قَالَ يَـٰبُنَىَّ إِنِّىٓ أَرَىٰ فِى ٱلْمَنَامِ أَنِّىٓ أَذْبَحُكَ فَٱنظُرْ مَاذَا تَرَىٰ ۚ قَالَ يَـٰٓأَبَتِ ٱفْعَلْ مَا تُؤْمَرُ ۖ سَتَجِدُنِىٓ إِن شَآءَ ٱللَّهُ مِنَ ٱلصَّـٰبِرِينَ","en":"And when he reached with him [the age of] exertion,1 he said, \"O my son, indeed I have seen in a dream that I [must] sacrifice you, so see what you think.\" He said, \"O my father, do as you are commanded. You will find me, if Allāh wills, of the steadfast.\"","tr":"Falamma balagha maAAahu assaAAyaqala ya bunayya innee ara fee almanamiannee athbahuka fanthur mathatara qala ya abati ifAAal ma tu/marusatajidunee in shaa Allahu mina assabireen","juz":23,"page":449},{"s":37,"a":103,"key":"37:103","ar":"فَلَمَّآ أَسْلَمَا وَتَلَّهُۥ لِلْجَبِينِ","en":"And when they had both submitted1 and he put him down upon his forehead,","tr":"Falamma aslama watallahuliljabeen","juz":23,"page":450},{"s":37,"a":104,"key":"37:104","ar":"وَنَـٰدَيْنَـٰهُ أَن يَـٰٓإِبْرَٰهِيمُ","en":"We called to him, \"O Abraham,","tr":"Wanadaynahu an ya ibraheem","juz":23,"page":450},{"s":37,"a":105,"key":"37:105","ar":"قَدْ صَدَّقْتَ ٱلرُّءْيَآ ۚ إِنَّا كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ","en":"You have fulfilled the vision.\" Indeed, We thus reward the doers of good.","tr":"Qad saddaqta arru/yainna kathalika najzee almuhsineen","juz":23,"page":450},{"s":37,"a":106,"key":"37:106","ar":"إِنَّ هَـٰذَا لَهُوَ ٱلْبَلَـٰٓؤُا۟ ٱلْمُبِينُ","en":"Indeed, this was the clear trial.","tr":"Inna hatha lahuwa albalaoalmubeen","juz":23,"page":450},{"s":37,"a":107,"key":"37:107","ar":"وَفَدَيْنَـٰهُ بِذِبْحٍ عَظِيمٍ","en":"And We ransomed him with a great sacrifice,1","tr":"Wafadaynahu bithibhinAAatheem","juz":23,"page":450},{"s":37,"a":108,"key":"37:108","ar":"وَتَرَكْنَا عَلَيْهِ فِى ٱلْـَٔاخِرِينَ","en":"And We left for him [favorable mention] among later generations:","tr":"Watarakna AAalayhi fee al-akhireen","juz":23,"page":450},{"s":37,"a":109,"key":"37:109","ar":"سَلَـٰمٌ عَلَىٰٓ إِبْرَٰهِيمَ","en":"\"Peace upon Abraham.\"","tr":"Salamun AAala ibraheem","juz":23,"page":450},{"s":37,"a":110,"key":"37:110","ar":"كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ","en":"Indeed, We thus reward the doers of good.","tr":"Kathalika najzee almuhsineen","juz":23,"page":450},{"s":37,"a":111,"key":"37:111","ar":"إِنَّهُۥ مِنْ عِبَادِنَا ٱلْمُؤْمِنِينَ","en":"Indeed, he was of Our believing servants.","tr":"Innahu min AAibadinaalmu/mineen","juz":23,"page":450},{"s":37,"a":112,"key":"37:112","ar":"وَبَشَّرْنَـٰهُ بِإِسْحَـٰقَ نَبِيًّا مِّنَ ٱلصَّـٰلِحِينَ","en":"And We gave him good tidings of Isaac, a prophet from among the righteous.1","tr":"Wabashsharnahu bi-ishaqanabiyyan mina assaliheen","juz":23,"page":450},{"s":37,"a":113,"key":"37:113","ar":"وَبَـٰرَكْنَا عَلَيْهِ وَعَلَىٰٓ إِسْحَـٰقَ ۚ وَمِن ذُرِّيَّتِهِمَا مُحْسِنٌ وَظَالِمٌ لِّنَفْسِهِۦ مُبِينٌ","en":"And We blessed him and Isaac. But among their descendants is the doer of good and the clearly unjust to himself [i.e., sinner].","tr":"Wabarakna AAalayhi waAAalaishaqa wamin thurriyyatihima muhsinunwathalimun linafsihi mubeen","juz":23,"page":450},{"s":37,"a":114,"key":"37:114","ar":"وَلَقَدْ مَنَنَّا عَلَىٰ مُوسَىٰ وَهَـٰرُونَ","en":"And We did certainly confer favor upon Moses and Aaron.","tr":"Walaqad mananna AAala moosawaharoon","juz":23,"page":450},{"s":37,"a":115,"key":"37:115","ar":"وَنَجَّيْنَـٰهُمَا وَقَوْمَهُمَا مِنَ ٱلْكَرْبِ ٱلْعَظِيمِ","en":"And We saved them and their people from the great affliction,","tr":"Wanajjaynahuma waqawmahumamina alkarbi alAAatheem","juz":23,"page":450},{"s":37,"a":116,"key":"37:116","ar":"وَنَصَرْنَـٰهُمْ فَكَانُوا۟ هُمُ ٱلْغَـٰلِبِينَ","en":"And We supported them so it was they who overcame.","tr":"Wanasarnahum fakanoohumu alghalibeen","juz":23,"page":450},{"s":37,"a":117,"key":"37:117","ar":"وَءَاتَيْنَـٰهُمَا ٱلْكِتَـٰبَ ٱلْمُسْتَبِينَ","en":"And We gave them the explicit Scripture [i.e., the Torah],","tr":"Waataynahuma alkitabaalmustabeen","juz":23,"page":450},{"s":37,"a":118,"key":"37:118","ar":"وَهَدَيْنَـٰهُمَا ٱلصِّرَٰطَ ٱلْمُسْتَقِيمَ","en":"And We guided them on the straight path.","tr":"Wahadaynahuma assirataalmustaqeem","juz":23,"page":450},{"s":37,"a":119,"key":"37:119","ar":"وَتَرَكْنَا عَلَيْهِمَا فِى ٱلْـَٔاخِرِينَ","en":"And We left for them [favorable mention] among later generations:","tr":"Watarakna AAalayhima fee al-akhireen","juz":23,"page":450},{"s":37,"a":120,"key":"37:120","ar":"سَلَـٰمٌ عَلَىٰ مُوسَىٰ وَهَـٰرُونَ","en":"\"Peace upon Moses and Aaron.\"","tr":"Salamun AAala moosawaharoon","juz":23,"page":450},{"s":37,"a":121,"key":"37:121","ar":"إِنَّا كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ","en":"Indeed, We thus reward the doers of good.","tr":"Inna kathalika najzee almuhsineen","juz":23,"page":450},{"s":37,"a":122,"key":"37:122","ar":"إِنَّهُمَا مِنْ عِبَادِنَا ٱلْمُؤْمِنِينَ","en":"Indeed, they were of Our believing servants.","tr":"Innahuma min AAibadinaalmu/mineen","juz":23,"page":450},{"s":37,"a":123,"key":"37:123","ar":"وَإِنَّ إِلْيَاسَ لَمِنَ ٱلْمُرْسَلِينَ","en":"And indeed, Elias was from among the messengers,","tr":"Wa-inna ilyasa lamina almursaleen","juz":23,"page":450},{"s":37,"a":124,"key":"37:124","ar":"إِذْ قَالَ لِقَوْمِهِۦٓ أَلَا تَتَّقُونَ","en":"When he said to his people, \"Will you not fear Allāh?","tr":"Ith qala liqawmihi alatattaqoon","juz":23,"page":450},{"s":37,"a":125,"key":"37:125","ar":"أَتَدْعُونَ بَعْلًا وَتَذَرُونَ أَحْسَنَ ٱلْخَـٰلِقِينَ","en":"Do you call upon Baʿl1 and leave the best of creators -","tr":"AtadAAoona baAAlan watatharoona ahsanaalkhaliqeen","juz":23,"page":450},{"s":37,"a":126,"key":"37:126","ar":"ٱللَّهَ رَبَّكُمْ وَرَبَّ ءَابَآئِكُمُ ٱلْأَوَّلِينَ","en":"Allāh, your Lord and the Lord of your first forefathers?\"","tr":"Allaha rabbakum warabba aba-ikumual-awwaleen","juz":23,"page":450},{"s":37,"a":127,"key":"37:127","ar":"فَكَذَّبُوهُ فَإِنَّهُمْ لَمُحْضَرُونَ","en":"And they denied him, so indeed, they will be brought [for punishment],","tr":"Fakaththaboohu fa-innahum lamuhdaroon","juz":23,"page":451},{"s":37,"a":128,"key":"37:128","ar":"إِلَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ","en":"Except the chosen servants of Allāh.","tr":"Illa AAibada Allahialmukhlaseen","juz":23,"page":451},{"s":37,"a":129,"key":"37:129","ar":"وَتَرَكْنَا عَلَيْهِ فِى ٱلْـَٔاخِرِينَ","en":"And We left for him [favorable mention] among later generations:","tr":"Watarakna AAalayhi fee al-akhireen","juz":23,"page":451},{"s":37,"a":130,"key":"37:130","ar":"سَلَـٰمٌ عَلَىٰٓ إِلْ يَاسِينَ","en":"\"Peace upon Elias.\"1","tr":"Salamun AAala il yaseen","juz":23,"page":451},{"s":37,"a":131,"key":"37:131","ar":"إِنَّا كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ","en":"Indeed, We thus reward the doers of good.","tr":"Inna kathalika najzee almuhsineen","juz":23,"page":451},{"s":37,"a":132,"key":"37:132","ar":"إِنَّهُۥ مِنْ عِبَادِنَا ٱلْمُؤْمِنِينَ","en":"Indeed, he was of Our believing servants.","tr":"Innahu min AAibadinaalmu/mineen","juz":23,"page":451},{"s":37,"a":133,"key":"37:133","ar":"وَإِنَّ لُوطًا لَّمِنَ ٱلْمُرْسَلِينَ","en":"And indeed, Lot was among the messengers.","tr":"Wa-inna lootan lamina almursaleen","juz":23,"page":451},{"s":37,"a":134,"key":"37:134","ar":"إِذْ نَجَّيْنَـٰهُ وَأَهْلَهُۥٓ أَجْمَعِينَ","en":"[So mention] when We saved him and his family, all,","tr":"Ith najjaynahu waahlahuajmaAAeen","juz":23,"page":451},{"s":37,"a":135,"key":"37:135","ar":"إِلَّا عَجُوزًا فِى ٱلْغَـٰبِرِينَ","en":"Except an old woman [i.e., his wife] among those who remained [with the evildoers].","tr":"Illa AAajoozan fee alghabireen","juz":23,"page":451},{"s":37,"a":136,"key":"37:136","ar":"ثُمَّ دَمَّرْنَا ٱلْـَٔاخَرِينَ","en":"Then We destroyed the others.","tr":"Thumma dammarna al-akhareen","juz":23,"page":451},{"s":37,"a":137,"key":"37:137","ar":"وَإِنَّكُمْ لَتَمُرُّونَ عَلَيْهِم مُّصْبِحِينَ","en":"And indeed, you pass by them in the morning","tr":"Wa-innakum latamurroona AAalayhim musbiheen","juz":23,"page":451},{"s":37,"a":138,"key":"37:138","ar":"وَبِٱلَّيْلِ ۗ أَفَلَا تَعْقِلُونَ","en":"And at night. Then will you not use reason?","tr":"Wabillayli afala taAAqiloon","juz":23,"page":451},{"s":37,"a":139,"key":"37:139","ar":"وَإِنَّ يُونُسَ لَمِنَ ٱلْمُرْسَلِينَ","en":"And indeed, Jonah was among the messengers.","tr":"Wa-inna yoonusa lamina almursaleen","juz":23,"page":451},{"s":37,"a":140,"key":"37:140","ar":"إِذْ أَبَقَ إِلَى ٱلْفُلْكِ ٱلْمَشْحُونِ","en":"[Mention] when he ran away to the laden ship.","tr":"Ith abaqa ila alfulki almashhoon","juz":23,"page":451},{"s":37,"a":141,"key":"37:141","ar":"فَسَاهَمَ فَكَانَ مِنَ ٱلْمُدْحَضِينَ","en":"And he drew lots1 and was among the losers.","tr":"Fasahama fakana mina almudhadeen","juz":23,"page":451},{"s":37,"a":142,"key":"37:142","ar":"فَٱلْتَقَمَهُ ٱلْحُوتُ وَهُوَ مُلِيمٌ","en":"Then the fish swallowed him, while he was blameworthy.1","tr":"Faltaqamahu alhootu wahuwamuleem","juz":23,"page":451},{"s":37,"a":143,"key":"37:143","ar":"فَلَوْلَآ أَنَّهُۥ كَانَ مِنَ ٱلْمُسَبِّحِينَ","en":"And had he not been of those who exalt Allāh,","tr":"Falawla annahu kana minaalmusabbiheen","juz":23,"page":451},{"s":37,"a":144,"key":"37:144","ar":"لَلَبِثَ فِى بَطْنِهِۦٓ إِلَىٰ يَوْمِ يُبْعَثُونَ","en":"He would have remained inside its belly until the Day they are resurrected.1","tr":"Lalabitha fee batnihi ilayawmi yubAAathoon","juz":23,"page":451},{"s":37,"a":145,"key":"37:145","ar":"۞ فَنَبَذْنَـٰهُ بِٱلْعَرَآءِ وَهُوَ سَقِيمٌ","en":"But We threw him onto the open shore while he was ill.","tr":"Fanabathnahu bilAAara-iwahuwa saqeem","juz":23,"page":451},{"s":37,"a":146,"key":"37:146","ar":"وَأَنۢبَتْنَا عَلَيْهِ شَجَرَةً مِّن يَقْطِينٍ","en":"And We caused to grow over him a gourd vine.1","tr":"Waanbatna AAalayhi shajaratan minyaqteen","juz":23,"page":451},{"s":37,"a":147,"key":"37:147","ar":"وَأَرْسَلْنَـٰهُ إِلَىٰ مِا۟ئَةِ أَلْفٍ أَوْ يَزِيدُونَ","en":"And We sent him1 to [his people of] a hundred thousand or more.","tr":"Waarsalnahu ila mi-ati alfinaw yazeedoon","juz":23,"page":451},{"s":37,"a":148,"key":"37:148","ar":"فَـَٔامَنُوا۟ فَمَتَّعْنَـٰهُمْ إِلَىٰ حِينٍ","en":"And they believed, so We gave them enjoyment [of life] for a time.","tr":"Faamanoo famattaAAnahum ilaheen","juz":23,"page":451},{"s":37,"a":149,"key":"37:149","ar":"فَٱسْتَفْتِهِمْ أَلِرَبِّكَ ٱلْبَنَاتُ وَلَهُمُ ٱلْبَنُونَ","en":"So inquire of them, [O Muḥammad], \"Does your Lord have daughters while they have sons?1","tr":"Fastaftihim alirabbika albanatuwalahumu albanoon","juz":23,"page":451},{"s":37,"a":150,"key":"37:150","ar":"أَمْ خَلَقْنَا ٱلْمَلَـٰٓئِكَةَ إِنَـٰثًا وَهُمْ شَـٰهِدُونَ","en":"Or did We create the angels as females while they were witnesses?\"","tr":"Am khalaqna almala-ikata inathanwahum shahidoon","juz":23,"page":451},{"s":37,"a":151,"key":"37:151","ar":"أَلَآ إِنَّهُم مِّنْ إِفْكِهِمْ لَيَقُولُونَ","en":"Unquestionably, it is out of their [invented] falsehood that they say,","tr":"Ala innahum min ifkihim layaqooloon","juz":23,"page":451},{"s":37,"a":152,"key":"37:152","ar":"وَلَدَ ٱللَّهُ وَإِنَّهُمْ لَكَـٰذِبُونَ","en":"\"Allāh has begotten,\" and indeed, they are liars.","tr":"Walada Allahu wa-innahum lakathiboon","juz":23,"page":451},{"s":37,"a":153,"key":"37:153","ar":"أَصْطَفَى ٱلْبَنَاتِ عَلَى ٱلْبَنِينَ","en":"Has He chosen daughters over sons?","tr":"Astafa albanati AAalaalbaneen","juz":23,"page":451},{"s":37,"a":154,"key":"37:154","ar":"مَا لَكُمْ كَيْفَ تَحْكُمُونَ","en":"What is [wrong] with you? How do you make judgement?","tr":"Ma lakum kayfa tahkumoon","juz":23,"page":452},{"s":37,"a":155,"key":"37:155","ar":"أَفَلَا تَذَكَّرُونَ","en":"Then will you not be reminded?","tr":"Afala tathakkaroon","juz":23,"page":452},{"s":37,"a":156,"key":"37:156","ar":"أَمْ لَكُمْ سُلْطَـٰنٌ مُّبِينٌ","en":"Or do you have a clear authority?1","tr":"Am lakum sultanun mubeen","juz":23,"page":452},{"s":37,"a":157,"key":"37:157","ar":"فَأْتُوا۟ بِكِتَـٰبِكُمْ إِن كُنتُمْ صَـٰدِقِينَ","en":"Then produce your scripture, if you should be truthful.","tr":"Fa/too bikitabikum in kuntum sadiqeen","juz":23,"page":452},{"s":37,"a":158,"key":"37:158","ar":"وَجَعَلُوا۟ بَيْنَهُۥ وَبَيْنَ ٱلْجِنَّةِ نَسَبًا ۚ وَلَقَدْ عَلِمَتِ ٱلْجِنَّةُ إِنَّهُمْ لَمُحْضَرُونَ","en":"And they have made [i.e., claimed] between Him and the jinn a lineage, but the jinn have already known that they [who made such claims] will be brought [to punishment].","tr":"WajaAAaloo baynahu wabayna aljinnatinasaban walaqad AAalimati aljinnatu innahum lamuhdaroon","juz":23,"page":452},{"s":37,"a":159,"key":"37:159","ar":"سُبْحَـٰنَ ٱللَّهِ عَمَّا يَصِفُونَ","en":"Exalted is Allāh above what they describe,","tr":"Subhana Allahi AAammayasifoon","juz":23,"page":452},{"s":37,"a":160,"key":"37:160","ar":"إِلَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ","en":"Except the chosen servants of Allāh [who do not share in that sin].","tr":"Illa AAibada Allahialmukhlaseen","juz":23,"page":452},{"s":37,"a":161,"key":"37:161","ar":"فَإِنَّكُمْ وَمَا تَعْبُدُونَ","en":"So indeed, you [disbelievers] and whatever you worship,","tr":"Fa-innakum wama taAAbudoon","juz":23,"page":452},{"s":37,"a":162,"key":"37:162","ar":"مَآ أَنتُمْ عَلَيْهِ بِفَـٰتِنِينَ","en":"You cannot tempt [anyone] away from Him","tr":"Ma antum AAalayhi bifatineen","juz":23,"page":452},{"s":37,"a":163,"key":"37:163","ar":"إِلَّا مَنْ هُوَ صَالِ ٱلْجَحِيمِ","en":"Except he who is to [enter and] burn in the Hellfire.1","tr":"Illa man huwa sali aljaheem","juz":23,"page":452},{"s":37,"a":164,"key":"37:164","ar":"وَمَا مِنَّآ إِلَّا لَهُۥ مَقَامٌ مَّعْلُومٌ","en":"[The angels say],1 \"There is not among us any except that he has a known position.2","tr":"Wama minna illa lahumaqamun maAAloom","juz":23,"page":452},{"s":37,"a":165,"key":"37:165","ar":"وَإِنَّا لَنَحْنُ ٱلصَّآفُّونَ","en":"And indeed, we are those who line up [for prayer].","tr":"Wa-inna lanahnu assaffoon","juz":23,"page":452},{"s":37,"a":166,"key":"37:166","ar":"وَإِنَّا لَنَحْنُ ٱلْمُسَبِّحُونَ","en":"And indeed, we are those who exalt Allāh.\"","tr":"Wa-inna lanahnu almusabbihoon","juz":23,"page":452},{"s":37,"a":167,"key":"37:167","ar":"وَإِن كَانُوا۟ لَيَقُولُونَ","en":"And indeed, they [i.e., the disbelievers] used to say,1","tr":"Wa-in kanoo layaqooloon","juz":23,"page":452},{"s":37,"a":168,"key":"37:168","ar":"لَوْ أَنَّ عِندَنَا ذِكْرًا مِّنَ ٱلْأَوَّلِينَ","en":"\"If we had a message from [those of] the former peoples,","tr":"Law anna AAindana thikranmina al-awwaleen","juz":23,"page":452},{"s":37,"a":169,"key":"37:169","ar":"لَكُنَّا عِبَادَ ٱللَّهِ ٱلْمُخْلَصِينَ","en":"We would have been the chosen servants of Allāh.\"","tr":"Lakunna AAibada Allahialmukhlaseen","juz":23,"page":452},{"s":37,"a":170,"key":"37:170","ar":"فَكَفَرُوا۟ بِهِۦ ۖ فَسَوْفَ يَعْلَمُونَ","en":"But they disbelieved in it,1 so they are going to know.","tr":"Fakafaroo bihi fasawfa yaAAlamoon","juz":23,"page":452},{"s":37,"a":171,"key":"37:171","ar":"وَلَقَدْ سَبَقَتْ كَلِمَتُنَا لِعِبَادِنَا ٱلْمُرْسَلِينَ","en":"And Our word [i.e., decree] has already preceded for Our servants, the messengers,","tr":"Walaqad sabaqat kalimatuna liAAibadinaalmursaleen","juz":23,"page":452},{"s":37,"a":172,"key":"37:172","ar":"إِنَّهُمْ لَهُمُ ٱلْمَنصُورُونَ","en":"[That] indeed, they would be those given victory","tr":"Innahum lahumu almansooroon","juz":23,"page":452},{"s":37,"a":173,"key":"37:173","ar":"وَإِنَّ جُندَنَا لَهُمُ ٱلْغَـٰلِبُونَ","en":"And [that] indeed, Our soldiers [i.e., the believers] will be those who overcome.1","tr":"Wa-inna jundana lahumu alghaliboon","juz":23,"page":452},{"s":37,"a":174,"key":"37:174","ar":"فَتَوَلَّ عَنْهُمْ حَتَّىٰ حِينٍ","en":"So, [O Muḥammad], leave them for a time.","tr":"Fatawalla AAanhum hatta heen","juz":23,"page":452},{"s":37,"a":175,"key":"37:175","ar":"وَأَبْصِرْهُمْ فَسَوْفَ يُبْصِرُونَ","en":"And see [what will befall] them, for they are going to see.","tr":"Waabsirhum fasawfa yubsiroon","juz":23,"page":452},{"s":37,"a":176,"key":"37:176","ar":"أَفَبِعَذَابِنَا يَسْتَعْجِلُونَ","en":"Then for Our punishment are they impatient?","tr":"AfabiAAathabina yastaAAjiloon","juz":23,"page":452},{"s":37,"a":177,"key":"37:177","ar":"فَإِذَا نَزَلَ بِسَاحَتِهِمْ فَسَآءَ صَبَاحُ ٱلْمُنذَرِينَ","en":"But when it descends in their territory, then evil is the morning of those who were warned.","tr":"Fa-itha nazala bisahatihimfasaa sabahu almunthareen","juz":23,"page":452},{"s":37,"a":178,"key":"37:178","ar":"وَتَوَلَّ عَنْهُمْ حَتَّىٰ حِينٍ","en":"And leave them for a time.","tr":"Watawalla AAanhum hatta heen","juz":23,"page":452},{"s":37,"a":179,"key":"37:179","ar":"وَأَبْصِرْ فَسَوْفَ يُبْصِرُونَ","en":"And see, for they are going to see.","tr":"Waabsir fasawfa yubsiroon","juz":23,"page":452},{"s":37,"a":180,"key":"37:180","ar":"سُبْحَـٰنَ رَبِّكَ رَبِّ ٱلْعِزَّةِ عَمَّا يَصِفُونَ","en":"Exalted is your Lord, the Lord of might, above what they describe.","tr":"Subhana rabbika rabbi alAAizzatiAAamma yasifoon","juz":23,"page":452},{"s":37,"a":181,"key":"37:181","ar":"وَسَلَـٰمٌ عَلَى ٱلْمُرْسَلِينَ","en":"And peace upon the messengers.","tr":"Wasalamun AAala almursaleen","juz":23,"page":452},{"s":37,"a":182,"key":"37:182","ar":"وَٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَـٰلَمِينَ","en":"And praise to Allāh, Lord of the worlds.","tr":"Walhamdu lillahirabbi alAAalameen","juz":23,"page":452},{"s":38,"a":1,"key":"38:1","ar":" صٓ ۚ وَٱلْقُرْءَانِ ذِى ٱلذِّكْرِ","en":"Ṣād.1 By the Qur’ān containing reminder...2","tr":"Sad walqur-ani theeaththikr","juz":23,"page":453},{"s":38,"a":2,"key":"38:2","ar":"بَلِ ٱلَّذِينَ كَفَرُوا۟ فِى عِزَّةٍ وَشِقَاقٍ","en":"But those who disbelieve are in pride and dissension.","tr":"Bali allatheena kafaroo fee AAizzatinwashiqaq","juz":23,"page":453},{"s":38,"a":3,"key":"38:3","ar":"كَمْ أَهْلَكْنَا مِن قَبْلِهِم مِّن قَرْنٍ فَنَادَوا۟ وَّلَاتَ حِينَ مَنَاصٍ","en":"How many a generation have We destroyed before them, and they [then] called out; but it was not a time for escape.","tr":"Kam ahlakna min qablihim min qarninfanadaw walata heena manas","juz":23,"page":453},{"s":38,"a":4,"key":"38:4","ar":"وَعَجِبُوٓا۟ أَن جَآءَهُم مُّنذِرٌ مِّنْهُمْ ۖ وَقَالَ ٱلْكَـٰفِرُونَ هَـٰذَا سَـٰحِرٌ كَذَّابٌ","en":"And they wonder that there has come to them a warner [i.e., Prophet Muḥammad (ﷺ)] from among themselves. And the disbelievers say, \"This is a magician and a liar.","tr":"WaAAajiboo an jaahum munthirunminhum waqala alkafiroona hatha sahirunkaththab","juz":23,"page":453},{"s":38,"a":5,"key":"38:5","ar":"أَجَعَلَ ٱلْـَٔالِهَةَ إِلَـٰهًا وَٰحِدًا ۖ إِنَّ هَـٰذَا لَشَىْءٌ عُجَابٌ","en":"Has he made the gods [only] one God? Indeed, this is a curious thing.\"","tr":"AjaAAala al-alihata ilahan wahidaninna hatha lashay-on AAujab","juz":23,"page":453},{"s":38,"a":6,"key":"38:6","ar":"وَٱنطَلَقَ ٱلْمَلَأُ مِنْهُمْ أَنِ ٱمْشُوا۟ وَٱصْبِرُوا۟ عَلَىٰٓ ءَالِهَتِكُمْ ۖ إِنَّ هَـٰذَا لَشَىْءٌ يُرَادُ","en":"And the eminent among them went forth, [saying], \"Continue, and be patient over [the defense of] your gods. Indeed, this is a thing intended.1","tr":"Wantalaqa almalao minhum aniimshoo wasbiroo AAala alihatikuminna hatha lashay-on yurad","juz":23,"page":453},{"s":38,"a":7,"key":"38:7","ar":"مَا سَمِعْنَا بِهَـٰذَا فِى ٱلْمِلَّةِ ٱلْـَٔاخِرَةِ إِنْ هَـٰذَآ إِلَّا ٱخْتِلَـٰقٌ","en":"We have not heard of this in the latest religion.1 This is not but a fabrication.","tr":"Ma samiAAna bihatha feealmillati al-akhirati in hatha illa ikhtilaq","juz":23,"page":453},{"s":38,"a":8,"key":"38:8","ar":"أَءُنزِلَ عَلَيْهِ ٱلذِّكْرُ مِنۢ بَيْنِنَا ۚ بَلْ هُمْ فِى شَكٍّ مِّن ذِكْرِى ۖ بَل لَّمَّا يَذُوقُوا۟ عَذَابِ","en":"Has the message been revealed to him out of [all of] us?\" Rather, they are in doubt about My message. Rather, they have not yet tasted My punishment.","tr":"Aonzila AAalayhi aththikru minbaynina bal hum fee shakkin min thikree bal lammayathooqoo AAathab","juz":23,"page":453},{"s":38,"a":9,"key":"38:9","ar":"أَمْ عِندَهُمْ خَزَآئِنُ رَحْمَةِ رَبِّكَ ٱلْعَزِيزِ ٱلْوَهَّابِ","en":"Or do they have the depositories of the mercy of your Lord, the Exalted in Might, the Bestower?1","tr":"Am AAindahum khaza-inu rahmatirabbika alAAazeezi alwahhab","juz":23,"page":453},{"s":38,"a":10,"key":"38:10","ar":"أَمْ لَهُم مُّلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا ۖ فَلْيَرْتَقُوا۟ فِى ٱلْأَسْبَـٰبِ","en":"Or is theirs the dominion of the heavens and the earth and what is between them? Then let them ascend through [any] ways of access.1","tr":"Am lahum mulku assamawatiwal-ardi wama baynahuma falyartaqoofee al-asbab","juz":23,"page":453},{"s":38,"a":11,"key":"38:11","ar":"جُندٌ مَّا هُنَالِكَ مَهْزُومٌ مِّنَ ٱلْأَحْزَابِ","en":"[They are but] soldiers [who will be] defeated there among the companies [of disbelievers].","tr":"Jundun ma hunalika mahzoomunmina al-ahzab","juz":23,"page":453},{"s":38,"a":12,"key":"38:12","ar":"كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍ وَعَادٌ وَفِرْعَوْنُ ذُو ٱلْأَوْتَادِ","en":"The people of Noah denied before them, and [the tribe of] ʿAad and Pharaoh, the owner of stakes,1","tr":"Kaththabat qablahum qawmu noohinwaAAadun wafirAAawnu thoo al-awtad","juz":23,"page":453},{"s":38,"a":13,"key":"38:13","ar":"وَثَمُودُ وَقَوْمُ لُوطٍ وَأَصْحَـٰبُ لْـَٔيْكَةِ ۚ أُو۟لَـٰٓئِكَ ٱلْأَحْزَابُ","en":"And [the tribe of] Thamūd and the people of Lot and the companions of the thicket [i.e., people of Madyan]. Those are the companies.1","tr":"Wathamoodu waqawmu lootin waas-habual-aykati ola-ika al-ahzab","juz":23,"page":453},{"s":38,"a":14,"key":"38:14","ar":"إِن كُلٌّ إِلَّا كَذَّبَ ٱلرُّسُلَ فَحَقَّ عِقَابِ","en":"Each of them denied the messengers, so My penalty was justified.","tr":"In kullun illa kaththaba arrusulafahaqqa AAiqab","juz":23,"page":453},{"s":38,"a":15,"key":"38:15","ar":"وَمَا يَنظُرُ هَـٰٓؤُلَآءِ إِلَّا صَيْحَةً وَٰحِدَةً مَّا لَهَا مِن فَوَاقٍ","en":"And these [disbelievers] await not but one blast [of the Horn]; for it there will be no delay.1","tr":"Wama yanthuru haola-iilla sayhatan wahidatan ma lahamin fawaq","juz":23,"page":453},{"s":38,"a":16,"key":"38:16","ar":"وَقَالُوا۟ رَبَّنَا عَجِّل لَّنَا قِطَّنَا قَبْلَ يَوْمِ ٱلْحِسَابِ","en":"And they say, \"Our Lord, hasten for us our share [of the punishment] before the Day of Account.\"","tr":"Waqaloo rabbana AAajjil lanaqittana qabla yawmi alhisab","juz":23,"page":453},{"s":38,"a":17,"key":"38:17","ar":"ٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَٱذْكُرْ عَبْدَنَا دَاوُۥدَ ذَا ٱلْأَيْدِ ۖ إِنَّهُۥٓ أَوَّابٌ","en":"Be patient over what they say and remember Our servant, David, the possessor of strength; indeed, he was one who repeatedly turned back [to Allāh].","tr":"Isbir AAala mayaqooloona wathkur AAabdana dawooda thaal-aydi innahu awwab","juz":23,"page":454},{"s":38,"a":18,"key":"38:18","ar":"إِنَّا سَخَّرْنَا ٱلْجِبَالَ مَعَهُۥ يُسَبِّحْنَ بِٱلْعَشِىِّ وَٱلْإِشْرَاقِ","en":"Indeed, We subjected the mountains [to praise] with him, exalting [Allāh] in the [late] afternoon and [after] sunrise.","tr":"Inna sakhkharna aljibalamaAAahu yusabbihna bilAAashiyyi wal-ishraq","juz":23,"page":454},{"s":38,"a":19,"key":"38:19","ar":"وَٱلطَّيْرَ مَحْشُورَةً ۖ كُلٌّ لَّهُۥٓ أَوَّابٌ","en":"And the birds were assembled, all with him repeating [praises].","tr":"Wattayra mahshooratankullun lahu awwab","juz":23,"page":454},{"s":38,"a":20,"key":"38:20","ar":"وَشَدَدْنَا مُلْكَهُۥ وَءَاتَيْنَـٰهُ ٱلْحِكْمَةَ وَفَصْلَ ٱلْخِطَابِ","en":"And We strengthened his kingdom and gave him wisdom and discernment in speech.","tr":"Washadadna mulkahu waataynahualhikmata wafasla alkhitab","juz":23,"page":454},{"s":38,"a":21,"key":"38:21","ar":"۞ وَهَلْ أَتَىٰكَ نَبَؤُا۟ ٱلْخَصْمِ إِذْ تَسَوَّرُوا۟ ٱلْمِحْرَابَ","en":"And has there come to you the news of the adversaries, when they climbed over the wall of [his] prayer chamber -","tr":"Wahal ataka nabao alkhasmi ithtasawwaroo almihrab","juz":23,"page":454},{"s":38,"a":22,"key":"38:22","ar":"إِذْ دَخَلُوا۟ عَلَىٰ دَاوُۥدَ فَفَزِعَ مِنْهُمْ ۖ قَالُوا۟ لَا تَخَفْ ۖ خَصْمَانِ بَغَىٰ بَعْضُنَا عَلَىٰ بَعْضٍ فَٱحْكُم بَيْنَنَا بِٱلْحَقِّ وَلَا تُشْطِطْ وَٱهْدِنَآ إِلَىٰ سَوَآءِ ٱلصِّرَٰطِ","en":"When they entered upon David and he was alarmed by them? They said, \"Fear not. [We are] two adversaries, one of whom has wronged the other, so judge between us with truth and do not exceed [it] and guide us to the sound path.","tr":"Ith dakhaloo AAala dawoodafafaziAAa minhum qaloo la takhaf khasmanibagha baAAduna AAala baAAdinfahkum baynana bilhaqqi walatushtit wahdina ila sawa-iassirat","juz":23,"page":454},{"s":38,"a":23,"key":"38:23","ar":"إِنَّ هَـٰذَآ أَخِى لَهُۥ تِسْعٌ وَتِسْعُونَ نَعْجَةً وَلِىَ نَعْجَةٌ وَٰحِدَةٌ فَقَالَ أَكْفِلْنِيهَا وَعَزَّنِى فِى ٱلْخِطَابِ","en":"Indeed this, my brother, has ninety-nine ewes, and I have one ewe; so he said, 'Entrust her to me,' and he overpowered me in speech.\"","tr":"Inna hatha akhee lahu tisAAunwatisAAoona naAAjatan waliya naAAjatun wahidatun faqalaakfilneeha waAAazzanee fee alkhitab","juz":23,"page":454},{"s":38,"a":24,"key":"38:24","ar":"قَالَ لَقَدْ ظَلَمَكَ بِسُؤَالِ نَعْجَتِكَ إِلَىٰ نِعَاجِهِۦ ۖ وَإِنَّ كَثِيرًا مِّنَ ٱلْخُلَطَآءِ لَيَبْغِى بَعْضُهُمْ عَلَىٰ بَعْضٍ إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ وَقَلِيلٌ مَّا هُمْ ۗ وَظَنَّ دَاوُۥدُ أَنَّمَا فَتَنَّـٰهُ فَٱسْتَغْفَرَ رَبَّهُۥ وَخَرَّ رَاكِعًا وَأَنَابَ ۩","en":"[David] said, \"He has certainly wronged you in demanding your ewe [in addition] to his ewes. And indeed, many associates oppress one another, except for those who believe and do righteous deeds - and few are they.\" And David became certain that We had tried him, and he asked forgiveness of his Lord1 and fell down bowing [in prostration] and turned in repentance [to Allāh].","tr":"Qala laqad thalamakabisu-ali naAAjatika ila niAAajihi wa-innakatheeran mina alkhulata-i layabghee baAAduhum AAalabaAAdin illa allatheena amanoowaAAamiloo assalihati waqaleelun mahum wathanna dawoodu annama fatannahufastaghfara rabbahu wakharra rakiAAan waanab","juz":23,"page":454},{"s":38,"a":25,"key":"38:25","ar":"فَغَفَرْنَا لَهُۥ ذَٰلِكَ ۖ وَإِنَّ لَهُۥ عِندَنَا لَزُلْفَىٰ وَحُسْنَ مَـَٔابٍ","en":"So We forgave him that; and indeed, for him is nearness to Us and a good place of return.","tr":"Faghafarna lahu thalikawa-inna lahu AAindana lazulfa wahusna maab","juz":23,"page":454},{"s":38,"a":26,"key":"38:26","ar":"يَـٰدَاوُۥدُ إِنَّا جَعَلْنَـٰكَ خَلِيفَةً فِى ٱلْأَرْضِ فَٱحْكُم بَيْنَ ٱلنَّاسِ بِٱلْحَقِّ وَلَا تَتَّبِعِ ٱلْهَوَىٰ فَيُضِلَّكَ عَن سَبِيلِ ٱللَّهِ ۚ إِنَّ ٱلَّذِينَ يَضِلُّونَ عَن سَبِيلِ ٱللَّهِ لَهُمْ عَذَابٌ شَدِيدٌۢ بِمَا نَسُوا۟ يَوْمَ ٱلْحِسَابِ","en":"[We said], \"O David, indeed We have made you a successor upon the earth, so judge between the people in truth and do not follow [your own] desire, as it will lead you astray from the way of Allāh.\" Indeed, those who go astray from the way of Allāh will have a severe punishment for having forgotten the Day of Account.","tr":"Ya dawoodu inna jaAAalnakakhaleefatan fee al-ardi fahkum bayna annasibilhaqqi wala tattabiAAi alhawa fayudillakaAAan sabeeli Allahi inna allatheena yadilloonaAAan sabeeli Allahi lahum AAathabun shadeedun bimanasoo yawma alhisab","juz":23,"page":454},{"s":38,"a":27,"key":"38:27","ar":"وَمَا خَلَقْنَا ٱلسَّمَآءَ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا بَـٰطِلًا ۚ ذَٰلِكَ ظَنُّ ٱلَّذِينَ كَفَرُوا۟ ۚ فَوَيْلٌ لِّلَّذِينَ كَفَرُوا۟ مِنَ ٱلنَّارِ","en":"And We did not create the heaven and the earth and that between them aimlessly. That is the assumption of those who disbelieve, so woe to those who disbelieve from the Fire.","tr":"Wama khalaqna assamaawal-arda wama baynahuma batilanthalika thannu allatheena kafaroofawaylun lillatheena kafaroo mina annar","juz":23,"page":455},{"s":38,"a":28,"key":"38:28","ar":"أَمْ نَجْعَلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ كَٱلْمُفْسِدِينَ فِى ٱلْأَرْضِ أَمْ نَجْعَلُ ٱلْمُتَّقِينَ كَٱلْفُجَّارِ","en":"Or should We treat those who believe and do righteous deeds like corrupters in the land? Or should We treat those who fear Allāh like the wicked?","tr":"Am najAAalu allatheena amanoowaAAamiloo assalihati kalmufsideenafee al-ardi am najAAalu almuttaqeena kalfujjar","juz":23,"page":455},{"s":38,"a":29,"key":"38:29","ar":"كِتَـٰبٌ أَنزَلْنَـٰهُ إِلَيْكَ مُبَـٰرَكٌ لِّيَدَّبَّرُوٓا۟ ءَايَـٰتِهِۦ وَلِيَتَذَكَّرَ أُو۟لُوا۟ ٱلْأَلْبَـٰبِ","en":"[This is] a blessed Book which We have revealed to you, [O Muḥammad], that they might reflect upon its verses and that those of understanding would be reminded.","tr":"Kitabun anzalnahu ilayka mubarakunliyaddabbaroo ayatihi waliyatathakkara olooal-albab","juz":23,"page":455},{"s":38,"a":30,"key":"38:30","ar":"وَوَهَبْنَا لِدَاوُۥدَ سُلَيْمَـٰنَ ۚ نِعْمَ ٱلْعَبْدُ ۖ إِنَّهُۥٓ أَوَّابٌ","en":"And to David We gave Solomon. An excellent servant, indeed he was one repeatedly turning back [to Allāh].","tr":"Wawahabna lidawooda sulaymananiAAma alAAabdu innahu awwab","juz":23,"page":455},{"s":38,"a":31,"key":"38:31","ar":"إِذْ عُرِضَ عَلَيْهِ بِٱلْعَشِىِّ ٱلصَّـٰفِنَـٰتُ ٱلْجِيَادُ","en":"[Mention] when there were exhibited before him in the afternoon the poised [standing] racehorses.","tr":"Ith AAurida AAalayhi bilAAashiyyiassafinatu aljiyad","juz":23,"page":455},{"s":38,"a":32,"key":"38:32","ar":"فَقَالَ إِنِّىٓ أَحْبَبْتُ حُبَّ ٱلْخَيْرِ عَن ذِكْرِ رَبِّى حَتَّىٰ تَوَارَتْ بِٱلْحِجَابِ","en":"And he said, \"Indeed, I gave preference to the love of good [things] over the remembrance of my Lord until it [i.e., the sun] disappeared into the curtain [of darkness].\"","tr":"Faqala innee ahbabtu hubbaalkhayri AAan thikri rabbee hatta tawaratbilhijab","juz":23,"page":455},{"s":38,"a":33,"key":"38:33","ar":"رُدُّوهَا عَلَىَّ ۖ فَطَفِقَ مَسْحًۢا بِٱلسُّوقِ وَٱلْأَعْنَاقِ","en":"[He said], \"Return them to me,\" and set about striking1 [their] legs and necks.","tr":"Ruddooha AAalayya fatafiqa mashanbissooqi wal-aAAnaq","juz":23,"page":455},{"s":38,"a":34,"key":"38:34","ar":"وَلَقَدْ فَتَنَّا سُلَيْمَـٰنَ وَأَلْقَيْنَا عَلَىٰ كُرْسِيِّهِۦ جَسَدًا ثُمَّ أَنَابَ","en":"And We certainly tried Solomon and placed on his throne a body;1 then he returned.2","tr":"Walaqad fatanna sulaymanawaalqayna AAala kursiyyihi jasadan thumma anab","juz":23,"page":455},{"s":38,"a":35,"key":"38:35","ar":"قَالَ رَبِّ ٱغْفِرْ لِى وَهَبْ لِى مُلْكًا لَّا يَنۢبَغِى لِأَحَدٍ مِّنۢ بَعْدِىٓ ۖ إِنَّكَ أَنتَ ٱلْوَهَّابُ","en":"He said, \"My Lord, forgive me and grant me a kingdom such as will not belong to anyone after me. Indeed, You are the Bestower.\"","tr":"Qala rabbi ighfir lee wahab leemulkan la yanbaghee li-ahadin min baAAdee innakaanta alwahhab","juz":23,"page":455},{"s":38,"a":36,"key":"38:36","ar":"فَسَخَّرْنَا لَهُ ٱلرِّيحَ تَجْرِى بِأَمْرِهِۦ رُخَآءً حَيْثُ أَصَابَ","en":"So We subjected to him the wind blowing by his command, gently, wherever he directed,","tr":"Fasakhkharna lahu arreehatajree bi-amrihi rukhaan haythu asab","juz":23,"page":455},{"s":38,"a":37,"key":"38:37","ar":"وَٱلشَّيَـٰطِينَ كُلَّ بَنَّآءٍ وَغَوَّاصٍ","en":"And [also] the devils [of jinn] - every builder and diver.","tr":"Washshayateena kulla banna-inwaghawwas","juz":23,"page":455},{"s":38,"a":38,"key":"38:38","ar":"وَءَاخَرِينَ مُقَرَّنِينَ فِى ٱلْأَصْفَادِ","en":"And others bound together in irons.","tr":"Waakhareena muqarraneena fee al-asfad","juz":23,"page":455},{"s":38,"a":39,"key":"38:39","ar":"هَـٰذَا عَطَآؤُنَا فَٱمْنُنْ أَوْ أَمْسِكْ بِغَيْرِ حِسَابٍ","en":"[We said], \"This is Our gift, so grant or withhold without account.\"","tr":"Hatha AAataona famnunaw amsik bighayri hisab","juz":23,"page":455},{"s":38,"a":40,"key":"38:40","ar":"وَإِنَّ لَهُۥ عِندَنَا لَزُلْفَىٰ وَحُسْنَ مَـَٔابٍ","en":"And indeed, for him is nearness to Us and a good place of return.","tr":"Wa-inna lahu AAindana lazulfawahusna maab","juz":23,"page":455},{"s":38,"a":41,"key":"38:41","ar":"وَٱذْكُرْ عَبْدَنَآ أَيُّوبَ إِذْ نَادَىٰ رَبَّهُۥٓ أَنِّى مَسَّنِىَ ٱلشَّيْطَـٰنُ بِنُصْبٍ وَعَذَابٍ","en":"And remember Our servant Job, when he called to his Lord, \"Indeed, Satan has touched me with hardship and torment.\"","tr":"Wathkur AAabdanaayyooba ith nada rabbahu annee massaniya ashshaytanubinusbin waAAathab","juz":23,"page":455},{"s":38,"a":42,"key":"38:42","ar":"ٱرْكُضْ بِرِجْلِكَ ۖ هَـٰذَا مُغْتَسَلٌۢ بَارِدٌ وَشَرَابٌ","en":"[So he was told], \"Strike [the ground] with your foot; this is a [spring for a] cool bath and drink.\"","tr":"Orkud birijlika hathamughtasalun baridun washarab","juz":23,"page":455},{"s":38,"a":43,"key":"38:43","ar":"وَوَهَبْنَا لَهُۥٓ أَهْلَهُۥ وَمِثْلَهُم مَّعَهُمْ رَحْمَةً مِّنَّا وَذِكْرَىٰ لِأُو۟لِى ٱلْأَلْبَـٰبِ","en":"And We granted him his family and a like [number] with them as mercy from Us and a reminder for those of understanding.","tr":"Wawahabna lahu ahlahu wamithlahummaAAahum rahmatan minna wathikrali-olee al-albab","juz":23,"page":456},{"s":38,"a":44,"key":"38:44","ar":"وَخُذْ بِيَدِكَ ضِغْثًا فَٱضْرِب بِّهِۦ وَلَا تَحْنَثْ ۗ إِنَّا وَجَدْنَـٰهُ صَابِرًا ۚ نِّعْمَ ٱلْعَبْدُ ۖ إِنَّهُۥٓ أَوَّابٌ","en":"[We said], \"And take in your hand a bunch [of grass] and strike with it and do not break your oath.\"1 Indeed, We found him patient, an excellent servant. Indeed, he was one repeatedly turning back [to Allāh].","tr":"Wakhuth biyadika dighthan fadribbihi wala tahnath inna wajadnahu sabiranniAAma alAAabdu innahu awwab","juz":23,"page":456},{"s":38,"a":45,"key":"38:45","ar":"وَٱذْكُرْ عِبَـٰدَنَآ إِبْرَٰهِيمَ وَإِسْحَـٰقَ وَيَعْقُوبَ أُو۟لِى ٱلْأَيْدِى وَٱلْأَبْصَـٰرِ","en":"And remember Our servants, Abraham, Isaac and Jacob - those of strength and [religious] vision.","tr":"Wathkur AAibadanaibraheema wa-ishaqa wayaAAqooba olee al-aydee wal-absar","juz":23,"page":456},{"s":38,"a":46,"key":"38:46","ar":"إِنَّآ أَخْلَصْنَـٰهُم بِخَالِصَةٍ ذِكْرَى ٱلدَّارِ","en":"Indeed, We chose them for an exclusive quality: remembrance of the home [of the Hereafter].","tr":"Inna akhlasnahum bikhalisatinthikra addar","juz":23,"page":456},{"s":38,"a":47,"key":"38:47","ar":"وَإِنَّهُمْ عِندَنَا لَمِنَ ٱلْمُصْطَفَيْنَ ٱلْأَخْيَارِ","en":"And indeed they are, to Us, among the chosen and outstanding.","tr":"Wa-innahum AAindana lamina almustafaynaal-akhyar","juz":23,"page":456},{"s":38,"a":48,"key":"38:48","ar":"وَٱذْكُرْ إِسْمَـٰعِيلَ وَٱلْيَسَعَ وَذَا ٱلْكِفْلِ ۖ وَكُلٌّ مِّنَ ٱلْأَخْيَارِ","en":"And remember Ishmael, Elisha and Dhul-Kifl, and all are among the outstanding.","tr":"Wathkur ismaAAeelawa-ilyasaAAa watha alkifli wakullun mina al-akhyar","juz":23,"page":456},{"s":38,"a":49,"key":"38:49","ar":"هَـٰذَا ذِكْرٌ ۚ وَإِنَّ لِلْمُتَّقِينَ لَحُسْنَ مَـَٔابٍ","en":"This is a reminder. And indeed, for the righteous is a good place of return -","tr":"Hatha thikrun wa-innalilmuttaqeena lahusna maab","juz":23,"page":456},{"s":38,"a":50,"key":"38:50","ar":"جَنَّـٰتِ عَدْنٍ مُّفَتَّحَةً لَّهُمُ ٱلْأَبْوَٰبُ","en":"Gardens of perpetual residence, whose doors will be opened to them.","tr":"Jannati AAadnin mufattahatanlahumu al-abwab","juz":23,"page":456},{"s":38,"a":51,"key":"38:51","ar":"مُتَّكِـِٔينَ فِيهَا يَدْعُونَ فِيهَا بِفَـٰكِهَةٍ كَثِيرَةٍ وَشَرَابٍ","en":"Reclining within them, they will call therein for abundant fruit and drink.","tr":"Muttaki-eena feeha yadAAoona feehabifakihatin katheeratin washarab","juz":23,"page":456},{"s":38,"a":52,"key":"38:52","ar":"۞ وَعِندَهُمْ قَـٰصِرَٰتُ ٱلطَّرْفِ أَتْرَابٌ","en":"And with them will be women limiting [their] glances1 and of equal age.","tr":"WaAAindahum qasiratu attarfiatrab","juz":23,"page":456},{"s":38,"a":53,"key":"38:53","ar":"هَـٰذَا مَا تُوعَدُونَ لِيَوْمِ ٱلْحِسَابِ","en":"This is what you, [the righteous], are promised for the Day of Account.","tr":"Hatha ma tooAAadoona liyawmialhisab","juz":23,"page":456},{"s":38,"a":54,"key":"38:54","ar":"إِنَّ هَـٰذَا لَرِزْقُنَا مَا لَهُۥ مِن نَّفَادٍ","en":"Indeed, this is Our provision; for it there is no depletion.","tr":"Inna hatha larizquna malahu min nafad","juz":23,"page":456},{"s":38,"a":55,"key":"38:55","ar":"هَـٰذَا ۚ وَإِنَّ لِلطَّـٰغِينَ لَشَرَّ مَـَٔابٍ","en":"This [is so]. But indeed, for the transgressors is an evil place of return -","tr":"Hatha wa-inna littagheenalasharra maab","juz":23,"page":456},{"s":38,"a":56,"key":"38:56","ar":"جَهَنَّمَ يَصْلَوْنَهَا فَبِئْسَ ٱلْمِهَادُ","en":"Hell, which they will [enter to] burn, and wretched is the resting place.","tr":"Jahannama yaslawnaha fabi/saalmihad","juz":23,"page":456},{"s":38,"a":57,"key":"38:57","ar":"هَـٰذَا فَلْيَذُوقُوهُ حَمِيمٌ وَغَسَّاقٌ","en":"This - so let them taste it - is scalding water and [foul] purulence.","tr":"Hatha falyathooqoohu hameemunwaghassaq","juz":23,"page":456},{"s":38,"a":58,"key":"38:58","ar":"وَءَاخَرُ مِن شَكْلِهِۦٓ أَزْوَٰجٌ","en":"And other [punishments] of its type [in various] kinds.","tr":"Waakharu min shaklihi azwaj","juz":23,"page":456},{"s":38,"a":59,"key":"38:59","ar":"هَـٰذَا فَوْجٌ مُّقْتَحِمٌ مَّعَكُمْ ۖ لَا مَرْحَبًۢا بِهِمْ ۚ إِنَّهُمْ صَالُوا۟ ٱلنَّارِ","en":"[Its inhabitants will say], \"This is a company bursting in with you. No welcome for them. Indeed, they will burn in the Fire.\"","tr":"Hatha fawjun muqtahimunmaAAakum la marhaban bihim innahum saloo annar","juz":23,"page":456},{"s":38,"a":60,"key":"38:60","ar":"قَالُوا۟ بَلْ أَنتُمْ لَا مَرْحَبًۢا بِكُمْ ۖ أَنتُمْ قَدَّمْتُمُوهُ لَنَا ۖ فَبِئْسَ ٱلْقَرَارُ","en":"They will say, \"Nor you! No welcome for you. You, [our leaders], brought this upon us, and wretched is the settlement.\"","tr":"Qaloo bal antum la marhabanbikum antum qaddamtumoohu lana fabi/sa alqarar","juz":23,"page":456},{"s":38,"a":61,"key":"38:61","ar":"قَالُوا۟ رَبَّنَا مَن قَدَّمَ لَنَا هَـٰذَا فَزِدْهُ عَذَابًا ضِعْفًا فِى ٱلنَّارِ","en":"They will say, \"Our Lord, whoever brought this upon us - increase for him double punishment in the Fire.\"","tr":"Qaloo rabbana man qaddama lanahatha fazidhu AAathaban diAAfan fee annar","juz":23,"page":456},{"s":38,"a":62,"key":"38:62","ar":"وَقَالُوا۟ مَا لَنَا لَا نَرَىٰ رِجَالًا كُنَّا نَعُدُّهُم مِّنَ ٱلْأَشْرَارِ","en":"And they will say, \"Why do we not see men whom we used to count among the worst?1","tr":"Waqaloo ma lana lanara rijalan kunna naAAudduhum mina al-ashrar","juz":23,"page":457},{"s":38,"a":63,"key":"38:63","ar":"أَتَّخَذْنَـٰهُمْ سِخْرِيًّا أَمْ زَاغَتْ عَنْهُمُ ٱلْأَبْصَـٰرُ","en":"Is it [because] we took them in ridicule, or has [our] vision turned away from them?\"","tr":"Attakhathnahum sikhriyyan am zaghatAAanhumu al-absar","juz":23,"page":457},{"s":38,"a":64,"key":"38:64","ar":"إِنَّ ذَٰلِكَ لَحَقٌّ تَخَاصُمُ أَهْلِ ٱلنَّارِ","en":"Indeed, that is truth [i.e., reality] - the quarreling of the people of the Fire.","tr":"Inna thalika lahaqqun takhasumuahli annar","juz":23,"page":457},{"s":38,"a":65,"key":"38:65","ar":"قُلْ إِنَّمَآ أَنَا۠ مُنذِرٌ ۖ وَمَا مِنْ إِلَـٰهٍ إِلَّا ٱللَّهُ ٱلْوَٰحِدُ ٱلْقَهَّارُ","en":"Say, [O Muḥammad], \"I am only a warner, and there is not any deity except Allāh, the One, the Prevailing,1","tr":"Qul innama ana munthirunwama min ilahin illa Allahu alwahidualqahhar","juz":23,"page":457},{"s":38,"a":66,"key":"38:66","ar":"رَبُّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا ٱلْعَزِيزُ ٱلْغَفَّـٰرُ","en":"Lord of the heavens and the earth and whatever is between them, the Exalted in Might,1 the Perpetual Forgiver.\"2","tr":"Rabbu assamawati wal-ardiwama baynahuma alAAazeezu alghaffar","juz":23,"page":457},{"s":38,"a":67,"key":"38:67","ar":"قُلْ هُوَ نَبَؤٌا۟ عَظِيمٌ","en":"Say, \"It is great news","tr":"Qul huwa nabaon AAatheem","juz":23,"page":457},{"s":38,"a":68,"key":"38:68","ar":"أَنتُمْ عَنْهُ مُعْرِضُونَ","en":"From which you turn away.","tr":"Antum AAanhu muAAridoon","juz":23,"page":457},{"s":38,"a":69,"key":"38:69","ar":"مَا كَانَ لِىَ مِنْ عِلْمٍۭ بِٱلْمَلَإِ ٱلْأَعْلَىٰٓ إِذْ يَخْتَصِمُونَ","en":"I had no knowledge of the exalted assembly [of angels] when they were disputing [the creation of Adam].","tr":"Ma kana liya min AAilmin bilmala-ial-aAAla ith yakhtasimoon","juz":23,"page":457},{"s":38,"a":70,"key":"38:70","ar":"إِن يُوحَىٰٓ إِلَىَّ إِلَّآ أَنَّمَآ أَنَا۠ نَذِيرٌ مُّبِينٌ","en":"It has not been revealed to me except that I am a clear warner.\"","tr":"In yooha ilayya illa annamaana natheerun mubeen","juz":23,"page":457},{"s":38,"a":71,"key":"38:71","ar":"إِذْ قَالَ رَبُّكَ لِلْمَلَـٰٓئِكَةِ إِنِّى خَـٰلِقٌۢ بَشَرًا مِّن طِينٍ","en":"[So mention] when your Lord said to the angels, \"Indeed, I am going to create a human being from clay.","tr":"Ith qala rabbuka lilmala-ikatiinnee khaliqun basharan min teen","juz":23,"page":457},{"s":38,"a":72,"key":"38:72","ar":"فَإِذَا سَوَّيْتُهُۥ وَنَفَخْتُ فِيهِ مِن رُّوحِى فَقَعُوا۟ لَهُۥ سَـٰجِدِينَ","en":"So when I have proportioned him and breathed into him of My [created] soul,1 then fall down to him in prostration.\"","tr":"Fa-itha sawwaytuhu wanafakhtu feehimin roohee faqaAAoo lahu sajideen","juz":23,"page":457},{"s":38,"a":73,"key":"38:73","ar":"فَسَجَدَ ٱلْمَلَـٰٓئِكَةُ كُلُّهُمْ أَجْمَعُونَ","en":"So the angels prostrated - all of them entirely,","tr":"Fasajada almala-ikatu kulluhumajmaAAoon","juz":23,"page":457},{"s":38,"a":74,"key":"38:74","ar":"إِلَّآ إِبْلِيسَ ٱسْتَكْبَرَ وَكَانَ مِنَ ٱلْكَـٰفِرِينَ","en":"Except Iblees;1 he was arrogant and became among the disbelievers.","tr":"Illa ibleesa istakbara wakanamina alkafireen","juz":23,"page":457},{"s":38,"a":75,"key":"38:75","ar":"قَالَ يَـٰٓإِبْلِيسُ مَا مَنَعَكَ أَن تَسْجُدَ لِمَا خَلَقْتُ بِيَدَىَّ ۖ أَسْتَكْبَرْتَ أَمْ كُنتَ مِنَ ٱلْعَالِينَ","en":"[Allāh] said, \"O Iblees, what prevented you from prostrating to that which I created with My hands?1 Were you arrogant [then], or were you [already] among the haughty?\"","tr":"Qala ya ibleesu mamanaAAaka an tasjuda lima khalaqtu biyadayya astakbarta amkunta mina alAAaleen","juz":23,"page":457},{"s":38,"a":76,"key":"38:76","ar":"قَالَ أَنَا۠ خَيْرٌ مِّنْهُ ۖ خَلَقْتَنِى مِن نَّارٍ وَخَلَقْتَهُۥ مِن طِينٍ","en":"He said, \"I am better than him. You created me from fire and created him from clay.\"","tr":"Qala ana khayrun minhukhalaqtanee min narin wakhalaqtahu min teen","juz":23,"page":457},{"s":38,"a":77,"key":"38:77","ar":"قَالَ فَٱخْرُجْ مِنْهَا فَإِنَّكَ رَجِيمٌ","en":"[Allāh] said, \"Then get out of it [i.e., Paradise], for indeed, you are expelled.","tr":"Qala fakhruj minhafa-innaka rajeem","juz":23,"page":457},{"s":38,"a":78,"key":"38:78","ar":"وَإِنَّ عَلَيْكَ لَعْنَتِىٓ إِلَىٰ يَوْمِ ٱلدِّينِ","en":"And indeed, upon you is My curse until the Day of Recompense.\"","tr":"Wa-inna AAalayka laAAnatee ila yawmiaddeen","juz":23,"page":457},{"s":38,"a":79,"key":"38:79","ar":"قَالَ رَبِّ فَأَنظِرْنِىٓ إِلَىٰ يَوْمِ يُبْعَثُونَ","en":"He said, \"My Lord, then reprieve me until the Day they are resurrected.\"","tr":"Qala rabbi faanthirneeila yawmi yubAAathoon","juz":23,"page":457},{"s":38,"a":80,"key":"38:80","ar":"قَالَ فَإِنَّكَ مِنَ ٱلْمُنظَرِينَ","en":"[Allāh] said, \"So indeed, you are of those reprieved","tr":"Qala fa-innaka mina almunthareen","juz":23,"page":457},{"s":38,"a":81,"key":"38:81","ar":"إِلَىٰ يَوْمِ ٱلْوَقْتِ ٱلْمَعْلُومِ","en":"Until the Day of the time well-known.\"","tr":"Ila yawmi alwaqti almaAAloom","juz":23,"page":457},{"s":38,"a":82,"key":"38:82","ar":"قَالَ فَبِعِزَّتِكَ لَأُغْوِيَنَّهُمْ أَجْمَعِينَ","en":"[Iblees] said, \"By Your might, I will surely mislead them all.","tr":"Qala fabiAAizzatika laoghwiyannahumajmaAAeen","juz":23,"page":457},{"s":38,"a":83,"key":"38:83","ar":"إِلَّا عِبَادَكَ مِنْهُمُ ٱلْمُخْلَصِينَ","en":"Except, among them, Your chosen servants.\"","tr":"Illa AAibadaka minhumualmukhlaseen","juz":23,"page":457},{"s":38,"a":84,"key":"38:84","ar":"قَالَ فَٱلْحَقُّ وَٱلْحَقَّ أَقُولُ","en":"[Allāh] said, \"The truth [is My oath], and the truth I say -","tr":"Qala falhaqqu walhaqqaaqool","juz":23,"page":458},{"s":38,"a":85,"key":"38:85","ar":"لَأَمْلَأَنَّ جَهَنَّمَ مِنكَ وَمِمَّن تَبِعَكَ مِنْهُمْ أَجْمَعِينَ","en":"[That] I will surely fill Hell with you and those of them that follow you all together.\"","tr":"Laamlaanna jahannama minka wamimmantabiAAaka minhum ajmaAAeen","juz":23,"page":458},{"s":38,"a":86,"key":"38:86","ar":"قُلْ مَآ أَسْـَٔلُكُمْ عَلَيْهِ مِنْ أَجْرٍ وَمَآ أَنَا۠ مِنَ ٱلْمُتَكَلِّفِينَ","en":"Say, [O Muḥammad], \"I do not ask you for it [i.e., the Qur’ān] any payment, and I am not of the pretentious.","tr":"Qul ma as-alukum AAalayhi min ajrinwama ana mina almutakallifeen","juz":23,"page":458},{"s":38,"a":87,"key":"38:87","ar":"إِنْ هُوَ إِلَّا ذِكْرٌ لِّلْعَـٰلَمِينَ","en":"It is but a reminder to the worlds.","tr":"In huwa illa thikrun lilAAalameen","juz":23,"page":458},{"s":38,"a":88,"key":"38:88","ar":"وَلَتَعْلَمُنَّ نَبَأَهُۥ بَعْدَ حِينٍۭ","en":"And you will surely know [the truth of] its information after a time.\"","tr":"WalataAAlamunna nabaahu baAAda heen","juz":23,"page":458},{"s":39,"a":1,"key":"39:1","ar":" تَنزِيلُ ٱلْكِتَـٰبِ مِنَ ٱللَّهِ ٱلْعَزِيزِ ٱلْحَكِيمِ","en":"The revelation of the Book [i.e., the Qur’ān] is from Allāh, the Exalted in Might, the Wise.","tr":"Tanzeelu alkitabi mina AllahialAAazeezi alhakeem","juz":23,"page":458},{"s":39,"a":2,"key":"39:2","ar":"إِنَّآ أَنزَلْنَآ إِلَيْكَ ٱلْكِتَـٰبَ بِٱلْحَقِّ فَٱعْبُدِ ٱللَّهَ مُخْلِصًا لَّهُ ٱلدِّينَ","en":"Indeed, We have sent down to you the Book, [O Muḥammad], in truth. So worship Allāh, [being] sincere to Him in religion.","tr":"Inna anzalna ilayka alkitababilhaqqi faAAbudi Allaha mukhlisanlahu addeen","juz":23,"page":458},{"s":39,"a":3,"key":"39:3","ar":"أَلَا لِلَّهِ ٱلدِّينُ ٱلْخَالِصُ ۚ وَٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ مَا نَعْبُدُهُمْ إِلَّا لِيُقَرِّبُونَآ إِلَى ٱللَّهِ زُلْفَىٰٓ إِنَّ ٱللَّهَ يَحْكُمُ بَيْنَهُمْ فِى مَا هُمْ فِيهِ يَخْتَلِفُونَ ۗ إِنَّ ٱللَّهَ لَا يَهْدِى مَنْ هُوَ كَـٰذِبٌ كَفَّارٌ","en":"Unquestionably, for Allāh is the pure religion.1 And those who take protectors besides Him [say], \"We only worship them that they may bring us nearer to Allāh in position.\" Indeed, Allāh will judge between them concerning that over which they differ. Indeed, Allāh does not guide he who is a liar and [confirmed] disbeliever.","tr":"Ala lillahi addeenualkhalisu wallatheena ittakhathoomin doonihi awliyaa ma naAAbuduhum illaliyuqarriboona ila Allahi zulfa innaAllaha yahkumu baynahum fee ma hum feehiyakhtalifoona inna Allaha la yahdee man huwa kathibunkaffar","juz":23,"page":458},{"s":39,"a":4,"key":"39:4","ar":"لَّوْ أَرَادَ ٱللَّهُ أَن يَتَّخِذَ وَلَدًا لَّٱصْطَفَىٰ مِمَّا يَخْلُقُ مَا يَشَآءُ ۚ سُبْحَـٰنَهُۥ ۖ هُوَ ٱللَّهُ ٱلْوَٰحِدُ ٱلْقَهَّارُ","en":"If Allāh had intended to take a son, He could have chosen from what He creates whatever He willed. Exalted is He; He is Allāh, the One, the Prevailing.1","tr":"Law arada Allahu an yattakhithawaladan lastafa mimma yakhluqu mayashao subhanahu huwa Allahu alwahidualqahhar","juz":23,"page":458},{"s":39,"a":5,"key":"39:5","ar":"خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ ۖ يُكَوِّرُ ٱلَّيْلَ عَلَى ٱلنَّهَارِ وَيُكَوِّرُ ٱلنَّهَارَ عَلَى ٱلَّيْلِ ۖ وَسَخَّرَ ٱلشَّمْسَ وَٱلْقَمَرَ ۖ كُلٌّ يَجْرِى لِأَجَلٍ مُّسَمًّى ۗ أَلَا هُوَ ٱلْعَزِيزُ ٱلْغَفَّـٰرُ","en":"He created the heavens and earth in truth. He wraps the night over the day and wraps the day over the night and has subjected the sun and the moon, each running [its course] for a specified term. Unquestionably, He is the Exalted in Might, the Perpetual Forgiver.1","tr":"Khalaqa assamawati wal-ardabilhaqqi yukawwiru allayla AAala annahariwayukawwiru annahara AAala allayliwasakhkhara ashshamsa walqamara kullun yajreeli-ajalin musamman ala huwa alAAazeezu alghaffar","juz":23,"page":458},{"s":39,"a":6,"key":"39:6","ar":"خَلَقَكُم مِّن نَّفْسٍ وَٰحِدَةٍ ثُمَّ جَعَلَ مِنْهَا زَوْجَهَا وَأَنزَلَ لَكُم مِّنَ ٱلْأَنْعَـٰمِ ثَمَـٰنِيَةَ أَزْوَٰجٍ ۚ يَخْلُقُكُمْ فِى بُطُونِ أُمَّهَـٰتِكُمْ خَلْقًا مِّنۢ بَعْدِ خَلْقٍ فِى ظُلُمَـٰتٍ ثَلَـٰثٍ ۚ ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ لَهُ ٱلْمُلْكُ ۖ لَآ إِلَـٰهَ إِلَّا هُوَ ۖ فَأَنَّىٰ تُصْرَفُونَ","en":"He created you from one soul. Then He made from it its mate, and He produced for you from the grazing livestock eight mates.1 He creates you in the wombs of your mothers, creation after creation, within three darknesses.2 That is Allāh, your Lord; to Him belongs dominion. There is no deity except Him, so how are you averted?","tr":"Khalaqakum min nafsin wahidatin thummajaAAala minha zawjaha waanzala lakum mina al-anAAamithamaniyata azwajin yakhluqukum fee butooniommahatikum khalqan min baAAdi khalqin fee thulumatinthalathin thalikumu Allahu rabbukum lahualmulku la ilaha illa huwa faanna tusrafoon","juz":23,"page":459},{"s":39,"a":7,"key":"39:7","ar":"إِن تَكْفُرُوا۟ فَإِنَّ ٱللَّهَ غَنِىٌّ عَنكُمْ ۖ وَلَا يَرْضَىٰ لِعِبَادِهِ ٱلْكُفْرَ ۖ وَإِن تَشْكُرُوا۟ يَرْضَهُ لَكُمْ ۗ وَلَا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَىٰ ۗ ثُمَّ إِلَىٰ رَبِّكُم مَّرْجِعُكُمْ فَيُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ ۚ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"If you disbelieve - indeed, Allāh is Free from need of you. And He does not approve for His servants disbelief. And if you are grateful, He approves [i.e., likes] it for you; and no bearer of burdens will bear the burden of another. Then to your Lord is your return, and He will inform you about what you used to do. Indeed, He is Knowing of that within the breasts.","tr":"In takfuroo fa-inna Allaha ghaniyyunAAankum wala yarda liAAibadihi alkufra wa-intashkuroo yardahu lakum wala taziru waziratunwizra okhra thumma ila rabbikum marjiAAukumfayunabbi-okum bima kuntum taAAmaloona innahu AAaleemun bithatiassudoor","juz":23,"page":459},{"s":39,"a":8,"key":"39:8","ar":"۞ وَإِذَا مَسَّ ٱلْإِنسَـٰنَ ضُرٌّ دَعَا رَبَّهُۥ مُنِيبًا إِلَيْهِ ثُمَّ إِذَا خَوَّلَهُۥ نِعْمَةً مِّنْهُ نَسِىَ مَا كَانَ يَدْعُوٓا۟ إِلَيْهِ مِن قَبْلُ وَجَعَلَ لِلَّهِ أَندَادًا لِّيُضِلَّ عَن سَبِيلِهِۦ ۚ قُلْ تَمَتَّعْ بِكُفْرِكَ قَلِيلًا ۖ إِنَّكَ مِنْ أَصْحَـٰبِ ٱلنَّارِ","en":"And when adversity touches man, he calls upon his Lord, turning to Him [alone]; then when He bestows on him a favor from Himself, he forgets Him whom he called upon before,1 and he attributes to Allāh equals to mislead [people] from His way. Say, \"Enjoy your disbelief for a little; indeed, you are of the companions of the Fire.\"","tr":"Wa-itha massa al-insana durrundaAAa rabbahu muneeban ilayhi thumma ithakhawwalahu niAAmatan minhu nasiya ma kana yadAAooilayhi min qablu wajaAAala lillahi andadan liyudillaAAan sabeelihi qul tamattaAA bikufrika qaleelan innaka min as-habiannar","juz":23,"page":459},{"s":39,"a":9,"key":"39:9","ar":"أَمَّنْ هُوَ قَـٰنِتٌ ءَانَآءَ ٱلَّيْلِ سَاجِدًا وَقَآئِمًا يَحْذَرُ ٱلْـَٔاخِرَةَ وَيَرْجُوا۟ رَحْمَةَ رَبِّهِۦ ۗ قُلْ هَلْ يَسْتَوِى ٱلَّذِينَ يَعْلَمُونَ وَٱلَّذِينَ لَا يَعْلَمُونَ ۗ إِنَّمَا يَتَذَكَّرُ أُو۟لُوا۟ ٱلْأَلْبَـٰبِ","en":"Is one who is devoutly obedient during periods of the night, prostrating and standing [in prayer], fearing the Hereafter and hoping for the mercy of his Lord, [like one who does not]? Say, \"Are those who know equal to those who do not know?\" Only they will remember [who are] people of understanding.","tr":"Amman huwa qanitun anaaallayli sajidan waqa-iman yahtharu al-akhiratawayarjoo rahmata rabbihi qul hal yastawee allatheenayaAAlamoona wallatheena la yaAAlamoonainnama yatathakkaru oloo al-albab","juz":23,"page":459},{"s":39,"a":10,"key":"39:10","ar":"قُلْ يَـٰعِبَادِ ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ رَبَّكُمْ ۚ لِلَّذِينَ أَحْسَنُوا۟ فِى هَـٰذِهِ ٱلدُّنْيَا حَسَنَةٌ ۗ وَأَرْضُ ٱللَّهِ وَٰسِعَةٌ ۗ إِنَّمَا يُوَفَّى ٱلصَّـٰبِرُونَ أَجْرَهُم بِغَيْرِ حِسَابٍ","en":"Say,1 \"O My servants who have believed, fear your Lord. For those who do good in this world is good, and the earth of Allāh is spacious. Indeed, the patient will be given their reward without account [i.e., limit].\"","tr":"Qul ya AAibadi allatheenaamanoo ittaqoo rabbakum lillatheena ahsanoofee hathihi addunya hasanatun waarduAllahi wasiAAatun innama yuwaffa assabiroonaajrahum bighayri hisab","juz":23,"page":459},{"s":39,"a":11,"key":"39:11","ar":"قُلْ إِنِّىٓ أُمِرْتُ أَنْ أَعْبُدَ ٱللَّهَ مُخْلِصًا لَّهُ ٱلدِّينَ","en":"Say, [O Muḥammad], \"Indeed, I have been commanded to worship Allāh, [being] sincere to Him in religion.","tr":"Qul innee omirtu an aAAbuda Allahamukhlisan lahu addeen","juz":23,"page":460},{"s":39,"a":12,"key":"39:12","ar":"وَأُمِرْتُ لِأَنْ أَكُونَ أَوَّلَ ٱلْمُسْلِمِينَ","en":"And I have been commanded to be the first [among you] of the Muslims.\"","tr":"Waomirtu li-an akoona awwala almuslimeen","juz":23,"page":460},{"s":39,"a":13,"key":"39:13","ar":"قُلْ إِنِّىٓ أَخَافُ إِنْ عَصَيْتُ رَبِّى عَذَابَ يَوْمٍ عَظِيمٍ","en":"Say, \"Indeed I fear, if I should disobey my Lord, the punishment of a tremendous Day.\"","tr":"Qul innee akhafu in AAasayturabbee AAathaba yawmin AAatheem","juz":23,"page":460},{"s":39,"a":14,"key":"39:14","ar":"قُلِ ٱللَّهَ أَعْبُدُ مُخْلِصًا لَّهُۥ دِينِى","en":"Say, \"Allāh [alone] do I worship, sincere to Him in my religion,","tr":"Quli Allaha aAAbudu mukhlisanlahu deenee","juz":23,"page":460},{"s":39,"a":15,"key":"39:15","ar":"فَٱعْبُدُوا۟ مَا شِئْتُم مِّن دُونِهِۦ ۗ قُلْ إِنَّ ٱلْخَـٰسِرِينَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ وَأَهْلِيهِمْ يَوْمَ ٱلْقِيَـٰمَةِ ۗ أَلَا ذَٰلِكَ هُوَ ٱلْخُسْرَانُ ٱلْمُبِينُ","en":"So worship what you will besides Him.\" Say, \"Indeed, the losers are the ones who will lose themselves and their families on the Day of Resurrection. Unquestionably, that is the manifest loss.\"","tr":"FaAAbudoo ma shi/tum mindoonihi qul inna alkhasireena allatheena khasirooanfusahum waahleehim yawma alqiyamati ala thalikahuwa alkhusranu almubeen","juz":23,"page":460},{"s":39,"a":16,"key":"39:16","ar":"لَهُم مِّن فَوْقِهِمْ ظُلَلٌ مِّنَ ٱلنَّارِ وَمِن تَحْتِهِمْ ظُلَلٌ ۚ ذَٰلِكَ يُخَوِّفُ ٱللَّهُ بِهِۦ عِبَادَهُۥ ۚ يَـٰعِبَادِ فَٱتَّقُونِ","en":"They will have canopies [i.e., layers] of fire above them and below them, canopies. By that Allāh threatens [i.e., warns] His servants. O My servants, then fear Me.","tr":"Lahum min fawqihim thulalunmina annari wamin tahtihim thulalunthalika yukhawwifu Allahu bihi AAibadahu yaAAibadi fattaqoon","juz":23,"page":460},{"s":39,"a":17,"key":"39:17","ar":"وَٱلَّذِينَ ٱجْتَنَبُوا۟ ٱلطَّـٰغُوتَ أَن يَعْبُدُوهَا وَأَنَابُوٓا۟ إِلَى ٱللَّهِ لَهُمُ ٱلْبُشْرَىٰ ۚ فَبَشِّرْ عِبَادِ","en":"But those who have avoided ṭāghūt,1 lest they worship it, and turned back to Allāh - for them are good tidings. So give good tidings to My servants","tr":"Wallatheena ijtanaboo attaghootaan yaAAbudooha waanaboo ila Allahilahumu albushra fabashshir AAibad","juz":23,"page":460},{"s":39,"a":18,"key":"39:18","ar":"ٱلَّذِينَ يَسْتَمِعُونَ ٱلْقَوْلَ فَيَتَّبِعُونَ أَحْسَنَهُۥٓ ۚ أُو۟لَـٰٓئِكَ ٱلَّذِينَ هَدَىٰهُمُ ٱللَّهُ ۖ وَأُو۟لَـٰٓئِكَ هُمْ أُو۟لُوا۟ ٱلْأَلْبَـٰبِ","en":"Who listen to speech and follow the best of it. Those are the ones Allāh has guided, and those are people of understanding.","tr":"Allatheena yastamiAAoona alqawlafayattabiAAoona ahsanahu ola-ika allatheenahadahumu Allahu waola-ika hum oloo al-albab","juz":23,"page":460},{"s":39,"a":19,"key":"39:19","ar":"أَفَمَنْ حَقَّ عَلَيْهِ كَلِمَةُ ٱلْعَذَابِ أَفَأَنتَ تُنقِذُ مَن فِى ٱلنَّارِ","en":"Then, is one who has deserved the decree of punishment [to be guided]? Then, can you save one who is in the Fire?","tr":"Afaman haqqa AAalayhi kalimatu alAAathabiafaanta tunqithu man fee annar","juz":23,"page":460},{"s":39,"a":20,"key":"39:20","ar":"لَـٰكِنِ ٱلَّذِينَ ٱتَّقَوْا۟ رَبَّهُمْ لَهُمْ غُرَفٌ مِّن فَوْقِهَا غُرَفٌ مَّبْنِيَّةٌ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ۖ وَعْدَ ٱللَّهِ ۖ لَا يُخْلِفُ ٱللَّهُ ٱلْمِيعَادَ","en":"But those who have feared their Lord - for them are chambers,1 above them chambers built high, beneath which rivers flow. [This is] the promise of Allāh. Allāh does not fail in [His] promise.","tr":"Lakini allatheena ittaqawrabbahum lahum ghurafun min fawqiha ghurafun mabniyyatuntajree min tahtiha al-anharu waAAda Allahila yukhlifu Allahu almeeAAad","juz":23,"page":460},{"s":39,"a":21,"key":"39:21","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ أَنزَلَ مِنَ ٱلسَّمَآءِ مَآءً فَسَلَكَهُۥ يَنَـٰبِيعَ فِى ٱلْأَرْضِ ثُمَّ يُخْرِجُ بِهِۦ زَرْعًا مُّخْتَلِفًا أَلْوَٰنُهُۥ ثُمَّ يَهِيجُ فَتَرَىٰهُ مُصْفَرًّا ثُمَّ يَجْعَلُهُۥ حُطَـٰمًا ۚ إِنَّ فِى ذَٰلِكَ لَذِكْرَىٰ لِأُو۟لِى ٱلْأَلْبَـٰبِ","en":"Do you not see that Allāh sends down rain from the sky and makes it flow as springs [and rivers] in the earth; then He produces thereby crops of varying colors; then they dry and you see them turned yellow; then He makes them [scattered] debris. Indeed in that is a reminder for those of understanding.","tr":"Alam tara anna Allaha anzala mina assama-imaan fasalakahu yanabeeAAa fee al-ardithumma yukhriju bihi zarAAan mukhtalifan alwanuhu thummayaheeju fatarahu musfarran thumma yajAAaluhu hutamaninna fee thalika lathikra li-olee al-albab","juz":23,"page":460},{"s":39,"a":22,"key":"39:22","ar":"أَفَمَن شَرَحَ ٱللَّهُ صَدْرَهُۥ لِلْإِسْلَـٰمِ فَهُوَ عَلَىٰ نُورٍ مِّن رَّبِّهِۦ ۚ فَوَيْلٌ لِّلْقَـٰسِيَةِ قُلُوبُهُم مِّن ذِكْرِ ٱللَّهِ ۚ أُو۟لَـٰٓئِكَ فِى ضَلَـٰلٍ مُّبِينٍ","en":"So is one whose breast Allāh has expanded to [accept] Islām and he is upon [i.e., guided by] a light from his Lord [like one whose heart rejects it]? Then woe to those whose hearts are hardened against the remembrance of Allāh. Those are in manifest error.","tr":"Afaman sharaha Allahu sadrahulil-islami fahuwa AAala noorin min rabbihi fawaylunlilqasiyati quloobuhum min thikri Allahi ola-ikafee dalalin mubeen","juz":23,"page":461},{"s":39,"a":23,"key":"39:23","ar":"ٱللَّهُ نَزَّلَ أَحْسَنَ ٱلْحَدِيثِ كِتَـٰبًا مُّتَشَـٰبِهًا مَّثَانِىَ تَقْشَعِرُّ مِنْهُ جُلُودُ ٱلَّذِينَ يَخْشَوْنَ رَبَّهُمْ ثُمَّ تَلِينُ جُلُودُهُمْ وَقُلُوبُهُمْ إِلَىٰ ذِكْرِ ٱللَّهِ ۚ ذَٰلِكَ هُدَى ٱللَّهِ يَهْدِى بِهِۦ مَن يَشَآءُ ۚ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِنْ هَادٍ","en":"Allāh has sent down the best statement: a consistent Book wherein is reiteration. The skins shiver therefrom of those who fear their Lord; then their skins and their hearts relax at the remembrance [i.e., mention] of Allāh. That is the guidance of Allāh by which He guides whom He wills. And one whom Allāh sends astray - for him there is no guide.","tr":"Allahu nazzala ahsana alhadeethikitaban mutashabihan mathaniya taqshaAAirruminhu juloodu allatheena yakhshawna rabbahum thummataleenu julooduhum waquloobuhum ila thikri Allahithalika huda Allahi yahdee bihi man yashaowaman yudlili Allahu fama lahu min had","juz":23,"page":461},{"s":39,"a":24,"key":"39:24","ar":"أَفَمَن يَتَّقِى بِوَجْهِهِۦ سُوٓءَ ٱلْعَذَابِ يَوْمَ ٱلْقِيَـٰمَةِ ۚ وَقِيلَ لِلظَّـٰلِمِينَ ذُوقُوا۟ مَا كُنتُمْ تَكْسِبُونَ","en":"Then is he who will shield with his face1 the worst of the punishment on the Day of Resurrection [like one secure from it]? And it will be said to the wrongdoers, \"Taste what you used to earn.\"","tr":"Afaman yattaqee biwajhihi soo-a alAAathabiyawma alqiyamati waqeela liththalimeenathooqoo ma kuntum taksiboon","juz":23,"page":461},{"s":39,"a":25,"key":"39:25","ar":"كَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ فَأَتَىٰهُمُ ٱلْعَذَابُ مِنْ حَيْثُ لَا يَشْعُرُونَ","en":"Those before them denied, and punishment came upon them from where they did not perceive.","tr":"Kaththaba allatheena minqablihim faatahumu alAAathabu min haythu layashAAuroon","juz":23,"page":461},{"s":39,"a":26,"key":"39:26","ar":"فَأَذَاقَهُمُ ٱللَّهُ ٱلْخِزْىَ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَلَعَذَابُ ٱلْـَٔاخِرَةِ أَكْبَرُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ","en":"So Allāh made them taste disgrace in worldly life. But the punishment of the Hereafter is greater, if they only knew.","tr":"Faathaqahumu Allahu alkhizyafee alhayati addunya walaAAathabual-akhirati akbaru law kanoo yaAAlamoon","juz":23,"page":461},{"s":39,"a":27,"key":"39:27","ar":"وَلَقَدْ ضَرَبْنَا لِلنَّاسِ فِى هَـٰذَا ٱلْقُرْءَانِ مِن كُلِّ مَثَلٍ لَّعَلَّهُمْ يَتَذَكَّرُونَ","en":"And We have certainly presented for the people in this Qur’ān from every [kind of] example - that they might remember.","tr":"Walaqad darabna linnasifee hatha alqur-ani min kulli mathalin laAAallahumyatathakkaroon","juz":23,"page":461},{"s":39,"a":28,"key":"39:28","ar":"قُرْءَانًا عَرَبِيًّا غَيْرَ ذِى عِوَجٍ لَّعَلَّهُمْ يَتَّقُونَ","en":"[It is] an Arabic Qur’ān, without any deviance1 that they might become righteous.2","tr":"Qur-anan AAarabiyyan ghayra theeAAiwajin laAAallahum yattaqoon","juz":23,"page":461},{"s":39,"a":29,"key":"39:29","ar":"ضَرَبَ ٱللَّهُ مَثَلًا رَّجُلًا فِيهِ شُرَكَآءُ مُتَشَـٰكِسُونَ وَرَجُلًا سَلَمًا لِّرَجُلٍ هَلْ يَسْتَوِيَانِ مَثَلًا ۚ ٱلْحَمْدُ لِلَّهِ ۚ بَلْ أَكْثَرُهُمْ لَا يَعْلَمُونَ","en":"Allāh presents an example: a man [i.e., slave] owned by quarreling partners and another belonging exclusively to one man - are they equal in comparison? Praise be to Allāh! But most of them do not know.","tr":"Daraba Allahu mathalan rajulanfeehi shurakao mutashakisoona warajulan salamanlirajulin hal yastawiyani mathalan alhamdu lillahibal aktharuhum la yaAAlamoon","juz":23,"page":461},{"s":39,"a":30,"key":"39:30","ar":"إِنَّكَ مَيِّتٌ وَإِنَّهُم مَّيِّتُونَ","en":"Indeed, you are to die, and indeed, they are to die.","tr":"Innaka mayyitun wa-innahum mayyitoon","juz":23,"page":461},{"s":39,"a":31,"key":"39:31","ar":"ثُمَّ إِنَّكُمْ يَوْمَ ٱلْقِيَـٰمَةِ عِندَ رَبِّكُمْ تَخْتَصِمُونَ","en":"Then indeed you, on the Day of Resurrection, before your Lord, will dispute.","tr":"Thumma innakum yawma alqiyamatiAAinda rabbikum takhtasimoon","juz":23,"page":461},{"s":39,"a":32,"key":"39:32","ar":"۞ فَمَنْ أَظْلَمُ مِمَّن كَذَبَ عَلَى ٱللَّهِ وَكَذَّبَ بِٱلصِّدْقِ إِذْ جَآءَهُۥٓ ۚ أَلَيْسَ فِى جَهَنَّمَ مَثْوًى لِّلْكَـٰفِرِينَ","en":"So who is more unjust than one who lies about Allāh and denies the truth when it has come to him? Is there not in Hell a residence for the disbelievers?","tr":"Faman athlamu mimman kathabaAAala Allahi wakaththaba bissidqiith jaahu alaysa fee jahannama mathwan lilkafireen","juz":24,"page":462},{"s":39,"a":33,"key":"39:33","ar":"وَٱلَّذِى جَآءَ بِٱلصِّدْقِ وَصَدَّقَ بِهِۦٓ ۙ أُو۟لَـٰٓئِكَ هُمُ ٱلْمُتَّقُونَ","en":"And the one who has brought the truth [i.e., the Prophet (ﷺ)] and [they who] believed in it - those are the righteous.","tr":"Wallathee jaa bissidqiwasaddaqa bihi ola-ika humu almuttaqoon","juz":24,"page":462},{"s":39,"a":34,"key":"39:34","ar":"لَهُم مَّا يَشَآءُونَ عِندَ رَبِّهِمْ ۚ ذَٰلِكَ جَزَآءُ ٱلْمُحْسِنِينَ","en":"They will have whatever they desire with their Lord. That is the reward of the doers of good -","tr":"Lahum ma yashaoona AAindarabbihim thalika jazao almuhsineen","juz":24,"page":462},{"s":39,"a":35,"key":"39:35","ar":"لِيُكَفِّرَ ٱللَّهُ عَنْهُمْ أَسْوَأَ ٱلَّذِى عَمِلُوا۟ وَيَجْزِيَهُمْ أَجْرَهُم بِأَحْسَنِ ٱلَّذِى كَانُوا۟ يَعْمَلُونَ","en":"That Allāh may remove from them the worst of what they did and reward them their due for the best of what they used to do.","tr":"Liyukaffira Allahu AAanhum aswaa allatheeAAamiloo wayajziyahum ajrahum bi-ahsani allathee kanooyaAAmaloon","juz":24,"page":462},{"s":39,"a":36,"key":"39:36","ar":"أَلَيْسَ ٱللَّهُ بِكَافٍ عَبْدَهُۥ ۖ وَيُخَوِّفُونَكَ بِٱلَّذِينَ مِن دُونِهِۦ ۚ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِنْ هَادٍ","en":"Is not Allāh sufficient for His Servant [i.e., Prophet Muḥammad (ﷺ)]? And [yet], they threaten you with those [they worship] other than Him. And whoever Allāh leaves astray - for him there is no guide.","tr":"Alaysa Allahu bikafin AAabdahuwayukhawwifoonaka billatheena min doonihi waman yudliliAllahu fama lahu min had","juz":24,"page":462},{"s":39,"a":37,"key":"39:37","ar":"وَمَن يَهْدِ ٱللَّهُ فَمَا لَهُۥ مِن مُّضِلٍّ ۗ أَلَيْسَ ٱللَّهُ بِعَزِيزٍ ذِى ٱنتِقَامٍ","en":"And whoever Allāh guides - for him there is no misleader. Is not Allāh Exalted in Might and Owner of Retribution?","tr":"Waman yahdi Allahu fama lahumin mudillin alaysa Allahu biAAazeezin theeintiqam","juz":24,"page":462},{"s":39,"a":38,"key":"39:38","ar":"وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ لَيَقُولُنَّ ٱللَّهُ ۚ قُلْ أَفَرَءَيْتُم مَّا تَدْعُونَ مِن دُونِ ٱللَّهِ إِنْ أَرَادَنِىَ ٱللَّهُ بِضُرٍّ هَلْ هُنَّ كَـٰشِفَـٰتُ ضُرِّهِۦٓ أَوْ أَرَادَنِى بِرَحْمَةٍ هَلْ هُنَّ مُمْسِكَـٰتُ رَحْمَتِهِۦ ۚ قُلْ حَسْبِىَ ٱللَّهُ ۖ عَلَيْهِ يَتَوَكَّلُ ٱلْمُتَوَكِّلُونَ","en":"And if you asked them, \"Who created the heavens and the earth?\" they would surely say, \"Allāh.\" Say, \"Then have you considered1 what you invoke besides Allāh? If Allāh intended me harm, are they removers of His harm; or if He intended me mercy, are they withholders of His mercy?\" Say, \"Sufficient for me is Allāh; upon Him [alone] rely the [wise] reliers.\"","tr":"Wala-in saaltahum man khalaqa assamawatiwal-arda layaqoolunna Allahu qul afaraaytumma tadAAoona min dooni Allahi in aradaniyaAllahu bidurrin hal hunna kashifatu durrihiaw aradanee birahmatin hal hunna mumsikaturahmatihi qul hasbiya Allahu AAalayhiyatawakkalu almutawakkiloon","juz":24,"page":462},{"s":39,"a":39,"key":"39:39","ar":"قُلْ يَـٰقَوْمِ ٱعْمَلُوا۟ عَلَىٰ مَكَانَتِكُمْ إِنِّى عَـٰمِلٌ ۖ فَسَوْفَ تَعْلَمُونَ","en":"Say, \"O my people, work according to your position, [for] indeed, I am working; and you are going to know","tr":"Qul ya qawmi iAAmaloo AAalamakanatikum innee AAamilun fasawfa taAAlamoon","juz":24,"page":462},{"s":39,"a":40,"key":"39:40","ar":"مَن يَأْتِيهِ عَذَابٌ يُخْزِيهِ وَيَحِلُّ عَلَيْهِ عَذَابٌ مُّقِيمٌ","en":"To whom will come a torment disgracing him and on whom will descend an enduring punishment.\"","tr":"Man ya/teehi AAathabun yukhzeehi wayahilluAAalayhi AAathabun muqeem","juz":24,"page":462},{"s":39,"a":41,"key":"39:41","ar":"إِنَّآ أَنزَلْنَا عَلَيْكَ ٱلْكِتَـٰبَ لِلنَّاسِ بِٱلْحَقِّ ۖ فَمَنِ ٱهْتَدَىٰ فَلِنَفْسِهِۦ ۖ وَمَن ضَلَّ فَإِنَّمَا يَضِلُّ عَلَيْهَا ۖ وَمَآ أَنتَ عَلَيْهِم بِوَكِيلٍ","en":"Indeed, We sent down to you the Book for the people in truth. So whoever is guided - it is for [the benefit of] his soul; and whoever goes astray only goes astray to its detriment. And you are not a manager [i.e., authority] over them.","tr":"Inna anzalna AAalayka alkitabalinnasi bilhaqqi famani ihtadafalinafsihi waman dalla fa-innama yadilluAAalayha wama anta AAalayhim biwakeel","juz":24,"page":463},{"s":39,"a":42,"key":"39:42","ar":"ٱللَّهُ يَتَوَفَّى ٱلْأَنفُسَ حِينَ مَوْتِهَا وَٱلَّتِى لَمْ تَمُتْ فِى مَنَامِهَا ۖ فَيُمْسِكُ ٱلَّتِى قَضَىٰ عَلَيْهَا ٱلْمَوْتَ وَيُرْسِلُ ٱلْأُخْرَىٰٓ إِلَىٰٓ أَجَلٍ مُّسَمًّى ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يَتَفَكَّرُونَ","en":"Allāh takes the souls at the time of their death, and those that do not die [He takes] during their sleep. Then He keeps those for which He has decreed death and releases the others for a specified term. Indeed in that are signs for a people who give thought.","tr":"Allahu yatawaffa al-anfusa heenamawtiha wallatee lam tamut fee manamihafayumsiku allatee qada AAalayha almawta wayursilual-okhra ila ajalin musamman inna fee thalikalaayatin liqawmin yatafakkaroon","juz":24,"page":463},{"s":39,"a":43,"key":"39:43","ar":"أَمِ ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ شُفَعَآءَ ۚ قُلْ أَوَلَوْ كَانُوا۟ لَا يَمْلِكُونَ شَيْـًٔا وَلَا يَعْقِلُونَ","en":"Or have they taken other than Allāh as intercessors? Say, \"Even though they do not possess [power over] anything, nor do they reason?\"","tr":"Ami ittakhathoo min dooni AllahishufaAAaa qul awa law kanoo la yamlikoonashay-an wala yaAAqiloon","juz":24,"page":463},{"s":39,"a":44,"key":"39:44","ar":"قُل لِّلَّهِ ٱلشَّفَـٰعَةُ جَمِيعًا ۖ لَّهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ ثُمَّ إِلَيْهِ تُرْجَعُونَ","en":"Say, \"To Allāh belongs [the right to allow] intercession entirely. To Him belongs the dominion of the heavens and the earth. Then to Him you will be returned.\"","tr":"Qul lillahi ashshafaAAatujameeAAan lahu mulku assamawati wal-ardithumma ilayhi turjaAAoon","juz":24,"page":463},{"s":39,"a":45,"key":"39:45","ar":"وَإِذَا ذُكِرَ ٱللَّهُ وَحْدَهُ ٱشْمَأَزَّتْ قُلُوبُ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ ۖ وَإِذَا ذُكِرَ ٱلَّذِينَ مِن دُونِهِۦٓ إِذَا هُمْ يَسْتَبْشِرُونَ","en":"And when Allāh is mentioned alone, the hearts of those who do not believe in the Hereafter shrink with aversion, but when those [worshipped] other than Him are mentioned, immediately they rejoice.","tr":"Wa-itha thukira Allahuwahdahu ishmaazzat quloobu allatheena layu/minoona bil-akhirati wa-itha thukiraallatheena min doonihi itha hum yastabshiroon","juz":24,"page":463},{"s":39,"a":46,"key":"39:46","ar":"قُلِ ٱللَّهُمَّ فَاطِرَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ عَـٰلِمَ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ أَنتَ تَحْكُمُ بَيْنَ عِبَادِكَ فِى مَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ","en":"Say, \"O Allāh, Creator of the heavens and the earth, Knower of the unseen and the witnessed, You will judge between your servants concerning that over which they used to differ.\"","tr":"Quli allahumma fatira assamawatiwal-ardi AAalima alghaybi washshahadatianta tahkumu bayna AAibadika fee ma kanoofeehi yakhtalifoon","juz":24,"page":463},{"s":39,"a":47,"key":"39:47","ar":"وَلَوْ أَنَّ لِلَّذِينَ ظَلَمُوا۟ مَا فِى ٱلْأَرْضِ جَمِيعًا وَمِثْلَهُۥ مَعَهُۥ لَٱفْتَدَوْا۟ بِهِۦ مِن سُوٓءِ ٱلْعَذَابِ يَوْمَ ٱلْقِيَـٰمَةِ ۚ وَبَدَا لَهُم مِّنَ ٱللَّهِ مَا لَمْ يَكُونُوا۟ يَحْتَسِبُونَ","en":"And if those who did wrong had all that is in the earth entirely and the like of it with it, they would [attempt to] ransom themselves thereby from the worst of the punishment on the Day of Resurrection. And there will appear to them from Allāh that which they had not taken into account.1","tr":"Walaw anna lillatheena thalamooma fee al-ardi jameeAAan wamithlahu maAAahu laftadawbihi min soo-i alAAathabi yawma alqiyamati wabadalahum mina Allahi ma lam yakoonoo yahtasiboon","juz":24,"page":463},{"s":39,"a":48,"key":"39:48","ar":"وَبَدَا لَهُمْ سَيِّـَٔاتُ مَا كَسَبُوا۟ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"And there will appear to them the evils they had earned, and they will be enveloped by what they used to ridicule.","tr":"Wabada lahum sayyi-atu makasaboo wahaqa bihim ma kanoo bihiyastahzi-oon","juz":24,"page":464},{"s":39,"a":49,"key":"39:49","ar":"فَإِذَا مَسَّ ٱلْإِنسَـٰنَ ضُرٌّ دَعَانَا ثُمَّ إِذَا خَوَّلْنَـٰهُ نِعْمَةً مِّنَّا قَالَ إِنَّمَآ أُوتِيتُهُۥ عَلَىٰ عِلْمٍۭ ۚ بَلْ هِىَ فِتْنَةٌ وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ","en":"And when adversity touches man, he calls upon Us; then when We bestow on him a favor from Us, he says, \"I have only been given it because of [my] knowledge.\" Rather, it is a trial, but most of them do not know.","tr":"Fa-itha massa al-insana durrundaAAana thumma itha khawwalnahuniAAmatan minna qala innama ooteetuhu AAalaAAilmin bal hiya fitnatun walakinna aktharahum layaAAlamoon","juz":24,"page":464},{"s":39,"a":50,"key":"39:50","ar":"قَدْ قَالَهَا ٱلَّذِينَ مِن قَبْلِهِمْ فَمَآ أَغْنَىٰ عَنْهُم مَّا كَانُوا۟ يَكْسِبُونَ","en":"Those before them had already said it, but they were not availed by what they used to earn.","tr":"Qad qalaha allatheenamin qablihim fama aghna AAanhum ma kanooyaksiboon","juz":24,"page":464},{"s":39,"a":51,"key":"39:51","ar":"فَأَصَابَهُمْ سَيِّـَٔاتُ مَا كَسَبُوا۟ ۚ وَٱلَّذِينَ ظَلَمُوا۟ مِنْ هَـٰٓؤُلَآءِ سَيُصِيبُهُمْ سَيِّـَٔاتُ مَا كَسَبُوا۟ وَمَا هُم بِمُعْجِزِينَ","en":"And the evil consequences of what they earned struck them. And those who have wronged of these [people] will be struck [i.e., afflicted] by the evil consequences of what they earned; and they will not cause failure.1","tr":"Faasabahum sayyi-atu makasaboo wallatheena thalamoo min haola-isayuseebuhum sayyi-atu ma kasaboo wamahum bimuAAjizeen","juz":24,"page":464},{"s":39,"a":52,"key":"39:52","ar":"أَوَلَمْ يَعْلَمُوٓا۟ أَنَّ ٱللَّهَ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يُؤْمِنُونَ","en":"Do they not know that Allāh extends provision for whom He wills and restricts [it]? Indeed in that are signs for a people who believe.","tr":"Awa lam yaAAlamoo anna Allaha yabsutuarrizqa liman yashao wayaqdiru inna fee thalikalaayatin liqawmin yu/minoon","juz":24,"page":464},{"s":39,"a":53,"key":"39:53","ar":"۞ قُلْ يَـٰعِبَادِىَ ٱلَّذِينَ أَسْرَفُوا۟ عَلَىٰٓ أَنفُسِهِمْ لَا تَقْنَطُوا۟ مِن رَّحْمَةِ ٱللَّهِ ۚ إِنَّ ٱللَّهَ يَغْفِرُ ٱلذُّنُوبَ جَمِيعًا ۚ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ","en":"Say, \"O My servants who have transgressed against themselves [by sinning], do not despair of the mercy of Allāh. Indeed, Allāh forgives all sins.1 Indeed, it is He who is the Forgiving, the Merciful.\"","tr":"Qul ya AAibadiya allatheenaasrafoo AAala anfusihim la taqnatoo min rahmatiAllahi inna Allaha yaghfiru aththunoobajameeAAan innahu huwa alghafooru arraheem","juz":24,"page":464},{"s":39,"a":54,"key":"39:54","ar":"وَأَنِيبُوٓا۟ إِلَىٰ رَبِّكُمْ وَأَسْلِمُوا۟ لَهُۥ مِن قَبْلِ أَن يَأْتِيَكُمُ ٱلْعَذَابُ ثُمَّ لَا تُنصَرُونَ","en":"And return [in repentance] to your Lord and submit to Him before the punishment comes upon you; then you will not be helped.","tr":"Waaneeboo ila rabbikum waaslimoo lahumin qabli an ya/tiyakumu alAAathabu thumma la tunsaroon","juz":24,"page":464},{"s":39,"a":55,"key":"39:55","ar":"وَٱتَّبِعُوٓا۟ أَحْسَنَ مَآ أُنزِلَ إِلَيْكُم مِّن رَّبِّكُم مِّن قَبْلِ أَن يَأْتِيَكُمُ ٱلْعَذَابُ بَغْتَةً وَأَنتُمْ لَا تَشْعُرُونَ","en":"And follow the best of what was revealed to you from your Lord [i.e., the Qur’ān] before the punishment comes upon you suddenly while you do not perceive,","tr":"WattabiAAoo ahsana maonzila ilaykum min rabbikum min qabli an ya/tiyakumu alAAathabubaghtatan waantum la tashAAuroon","juz":24,"page":464},{"s":39,"a":56,"key":"39:56","ar":"أَن تَقُولَ نَفْسٌ يَـٰحَسْرَتَىٰ عَلَىٰ مَا فَرَّطتُ فِى جَنۢبِ ٱللَّهِ وَإِن كُنتُ لَمِنَ ٱلسَّـٰخِرِينَ","en":"Lest a soul should say,1 \"Oh, [how great is] my regret over what I neglected in regard to Allāh and that I was among the mockers.\"","tr":"An taqoola nafsun ya hasrataAAala ma farrattu fee janbi Allahiwa-in kuntu lamina assakhireen","juz":24,"page":464},{"s":39,"a":57,"key":"39:57","ar":"أَوْ تَقُولَ لَوْ أَنَّ ٱللَّهَ هَدَىٰنِى لَكُنتُ مِنَ ٱلْمُتَّقِينَ","en":"Or [lest] it say, \"If only Allāh had guided me, I would have been among the righteous.\"","tr":"Aw taqoola law anna Allaha hadaneelakuntu mina almuttaqeen","juz":24,"page":465},{"s":39,"a":58,"key":"39:58","ar":"أَوْ تَقُولَ حِينَ تَرَى ٱلْعَذَابَ لَوْ أَنَّ لِى كَرَّةً فَأَكُونَ مِنَ ٱلْمُحْسِنِينَ","en":"Or [lest] it say when it sees the punishment, \"If only I had another turn1 so I could be among the doers of good.\"","tr":"Aw taqoola heena tara alAAathabalaw anna lee karratan faakoona mina almuhsineen","juz":24,"page":465},{"s":39,"a":59,"key":"39:59","ar":"بَلَىٰ قَدْ جَآءَتْكَ ءَايَـٰتِى فَكَذَّبْتَ بِهَا وَٱسْتَكْبَرْتَ وَكُنتَ مِنَ ٱلْكَـٰفِرِينَ","en":"But yes, there had come to you My verses, but you denied them and were arrogant, and you were among the disbelievers.","tr":"Bala qad jaatka ayateefakaththabta biha wastakbarta wakunta minaalkafireen","juz":24,"page":465},{"s":39,"a":60,"key":"39:60","ar":"وَيَوْمَ ٱلْقِيَـٰمَةِ تَرَى ٱلَّذِينَ كَذَبُوا۟ عَلَى ٱللَّهِ وُجُوهُهُم مُّسْوَدَّةٌ ۚ أَلَيْسَ فِى جَهَنَّمَ مَثْوًى لِّلْمُتَكَبِّرِينَ","en":"And on the Day of Resurrection you will see those who lied about Allāh [with] their faces blackened. Is there not in Hell a residence for the arrogant?","tr":"Wayawma alqiyamati tara allatheenakathaboo AAala Allahi wujoohuhum muswaddatunalaysa fee jahannama mathwan lilmutakabbireen","juz":24,"page":465},{"s":39,"a":61,"key":"39:61","ar":"وَيُنَجِّى ٱللَّهُ ٱلَّذِينَ ٱتَّقَوْا۟ بِمَفَازَتِهِمْ لَا يَمَسُّهُمُ ٱلسُّوٓءُ وَلَا هُمْ يَحْزَنُونَ","en":"And Allāh will save those who feared Him by their attainment;1 no evil will touch them, nor will they grieve.","tr":"Wayunajjee Allahu allatheenaittaqaw bimafazatihim la yamassuhumu assoo-owala hum yahzanoon","juz":24,"page":465},{"s":39,"a":62,"key":"39:62","ar":"ٱللَّهُ خَـٰلِقُ كُلِّ شَىْءٍ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ وَكِيلٌ","en":"Allāh is the Creator of all things, and He is, over all things, Disposer of affairs.","tr":"Allahu khaliqu kulli shay-inwahuwa AAala kulli shay-in wakeel","juz":24,"page":465},{"s":39,"a":63,"key":"39:63","ar":"لَّهُۥ مَقَالِيدُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۗ وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَـٰتِ ٱللَّهِ أُو۟لَـٰٓئِكَ هُمُ ٱلْخَـٰسِرُونَ","en":"To Him belong the keys of the heavens and the earth. And they who disbelieve in the verses of Allāh - it is those who are the losers.","tr":"Lahu maqaleedu assamawatiwal-ardi wallatheena kafaroo bi-ayatiAllahi ola-ika humu alkhasiroon","juz":24,"page":465},{"s":39,"a":64,"key":"39:64","ar":"قُلْ أَفَغَيْرَ ٱللَّهِ تَأْمُرُوٓنِّىٓ أَعْبُدُ أَيُّهَا ٱلْجَـٰهِلُونَ","en":"Say, [O Muḥammad], \"Is it other than Allāh that you order me to worship, O ignorant ones?\"","tr":"Qul afaghayra Allahi ta/muroonneeaAAbudu ayyuha aljahiloon","juz":24,"page":465},{"s":39,"a":65,"key":"39:65","ar":"وَلَقَدْ أُوحِىَ إِلَيْكَ وَإِلَى ٱلَّذِينَ مِن قَبْلِكَ لَئِنْ أَشْرَكْتَ لَيَحْبَطَنَّ عَمَلُكَ وَلَتَكُونَنَّ مِنَ ٱلْخَـٰسِرِينَ","en":"And it was already revealed to you and to those before you that if you should associate [anything] with Allāh, your work would surely become worthless, and you would surely be among the losers.","tr":"Walaqad oohiya ilayka wa-ilaallatheena min qablika la-in ashrakta layahbatannaAAamaluka walatakoonanna mina alkhasireen","juz":24,"page":465},{"s":39,"a":66,"key":"39:66","ar":"بَلِ ٱللَّهَ فَٱعْبُدْ وَكُن مِّنَ ٱلشَّـٰكِرِينَ","en":"Rather, worship [only] Allāh and be among the grateful.","tr":"Bali Allaha faAAbud wakunmina ashshakireen","juz":24,"page":465},{"s":39,"a":67,"key":"39:67","ar":"وَمَا قَدَرُوا۟ ٱللَّهَ حَقَّ قَدْرِهِۦ وَٱلْأَرْضُ جَمِيعًا قَبْضَتُهُۥ يَوْمَ ٱلْقِيَـٰمَةِ وَٱلسَّمَـٰوَٰتُ مَطْوِيَّـٰتٌۢ بِيَمِينِهِۦ ۚ سُبْحَـٰنَهُۥ وَتَعَـٰلَىٰ عَمَّا يُشْرِكُونَ","en":"They have not appraised Allāh with true appraisal,1 while the earth entirely will be [within] His grip2 on the Day of Resurrection, and the heavens will be folded in His right hand.3 Exalted is He and high above what they associate with Him.","tr":"Wama qadaroo Allaha haqqaqadrihi wal-ardu jameeAAan qabdatuhu yawmaalqiyamati wassamawatu matwiyyatunbiyameenihi subhanahu wataAAala AAammayushrikoon","juz":24,"page":465},{"s":39,"a":68,"key":"39:68","ar":"وَنُفِخَ فِى ٱلصُّورِ فَصَعِقَ مَن فِى ٱلسَّمَـٰوَٰتِ وَمَن فِى ٱلْأَرْضِ إِلَّا مَن شَآءَ ٱللَّهُ ۖ ثُمَّ نُفِخَ فِيهِ أُخْرَىٰ فَإِذَا هُمْ قِيَامٌ يَنظُرُونَ","en":"And the Horn will be blown, and whoever is in the heavens and whoever is on the earth will fall dead except whom Allāh wills. Then it will be blown again, and at once they will be standing, looking on.","tr":"Wanufikha fee assoori fasaAAiqaman fee assamawati waman fee al-ardiilla man shaa Allahu thumma nufikha feehiokhra fa-itha hum qiyamun yanthuroon","juz":24,"page":466},{"s":39,"a":69,"key":"39:69","ar":"وَأَشْرَقَتِ ٱلْأَرْضُ بِنُورِ رَبِّهَا وَوُضِعَ ٱلْكِتَـٰبُ وَجِا۟ىٓءَ بِٱلنَّبِيِّـۧنَ وَٱلشُّهَدَآءِ وَقُضِىَ بَيْنَهُم بِٱلْحَقِّ وَهُمْ لَا يُظْلَمُونَ","en":"And the earth will shine with the light of its Lord, and the record [of deeds] will be placed, and the prophets and the witnesses will be brought, and it will be judged between them in truth, and they will not be wronged.","tr":"Waashraqati al-ardu binoori rabbihawawudiAAa alkitabu wajee-a binnabiyyeenawashshuhada-i waqudiya baynahum bilhaqqiwahum la yuthlamoon","juz":24,"page":466},{"s":39,"a":70,"key":"39:70","ar":"وَوُفِّيَتْ كُلُّ نَفْسٍ مَّا عَمِلَتْ وَهُوَ أَعْلَمُ بِمَا يَفْعَلُونَ","en":"And every soul will be fully compensated [for] what it did; and He is most knowing1 of what they do.","tr":"Wawuffiyat kullu nafsin ma AAamilatwahuwa aAAlamu bima yafAAaloon","juz":24,"page":466},{"s":39,"a":71,"key":"39:71","ar":"وَسِيقَ ٱلَّذِينَ كَفَرُوٓا۟ إِلَىٰ جَهَنَّمَ زُمَرًا ۖ حَتَّىٰٓ إِذَا جَآءُوهَا فُتِحَتْ أَبْوَٰبُهَا وَقَالَ لَهُمْ خَزَنَتُهَآ أَلَمْ يَأْتِكُمْ رُسُلٌ مِّنكُمْ يَتْلُونَ عَلَيْكُمْ ءَايَـٰتِ رَبِّكُمْ وَيُنذِرُونَكُمْ لِقَآءَ يَوْمِكُمْ هَـٰذَا ۚ قَالُوا۟ بَلَىٰ وَلَـٰكِنْ حَقَّتْ كَلِمَةُ ٱلْعَذَابِ عَلَى ٱلْكَـٰفِرِينَ","en":"And those who disbelieved will be driven to Hell in groups until, when they reach it, its gates are opened and its keepers will say, \"Did there not come to you messengers from yourselves, reciting to you the verses of your Lord and warning you of the meeting of this Day of yours?\" They will say, \"Yes, but the word [i.e., decree] of punishment has come into effect upon the disbelievers.\"","tr":"Waseeqa allatheena kafaroo ilajahannama zumaran hatta itha jaoohafutihat abwabuha waqala lahumkhazanatuha alam ya/tikum rusulun minkum yatloonaAAalaykum ayati rabbikum wayunthiroonakumliqaa yawmikum hatha qaloo bala walakinhaqqat kalimatu alAAathabi AAala alkafireen","juz":24,"page":466},{"s":39,"a":72,"key":"39:72","ar":"قِيلَ ٱدْخُلُوٓا۟ أَبْوَٰبَ جَهَنَّمَ خَـٰلِدِينَ فِيهَا ۖ فَبِئْسَ مَثْوَى ٱلْمُتَكَبِّرِينَ","en":"[To them] it will be said, \"Enter the gates of Hell to abide eternally therein, and wretched is the residence of the arrogant.\"","tr":"Qeela odkhuloo abwaba jahannama khalideenafeeha fabi/sa mathwa almutakabbireen","juz":24,"page":466},{"s":39,"a":73,"key":"39:73","ar":"وَسِيقَ ٱلَّذِينَ ٱتَّقَوْا۟ رَبَّهُمْ إِلَى ٱلْجَنَّةِ زُمَرًا ۖ حَتَّىٰٓ إِذَا جَآءُوهَا وَفُتِحَتْ أَبْوَٰبُهَا وَقَالَ لَهُمْ خَزَنَتُهَا سَلَـٰمٌ عَلَيْكُمْ طِبْتُمْ فَٱدْخُلُوهَا خَـٰلِدِينَ","en":"But those who feared their Lord will be driven to Paradise in groups until, when they reach it while its gates have been opened and its keepers say, \"Peace be upon you; you have become pure; so enter it to abide eternally therein,\" [they will enter].1","tr":"Waseeqa allatheena ittaqaw rabbahumila aljannati zumaran hatta itha jaoohawafutihat abwabuha waqala lahumkhazanatuha salamun AAalaykum tibtum fadkhuloohakhalideen","juz":24,"page":466},{"s":39,"a":74,"key":"39:74","ar":"وَقَالُوا۟ ٱلْحَمْدُ لِلَّهِ ٱلَّذِى صَدَقَنَا وَعْدَهُۥ وَأَوْرَثَنَا ٱلْأَرْضَ نَتَبَوَّأُ مِنَ ٱلْجَنَّةِ حَيْثُ نَشَآءُ ۖ فَنِعْمَ أَجْرُ ٱلْعَـٰمِلِينَ","en":"And they will say, \"Praise to Allāh, who has fulfilled for us His promise and made us inherit the earth [so] we may settle in Paradise wherever we will. And excellent is the reward of [righteous] workers.\"","tr":"Waqaloo alhamdu lillahiallathee sadaqana waAAdahu waawrathanaal-arda natabawwao mina aljannati haythu nashaofaniAAma ajru alAAamileen","juz":24,"page":466},{"s":39,"a":75,"key":"39:75","ar":"وَتَرَى ٱلْمَلَـٰٓئِكَةَ حَآفِّينَ مِنْ حَوْلِ ٱلْعَرْشِ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْ ۖ وَقُضِىَ بَيْنَهُم بِٱلْحَقِّ وَقِيلَ ٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَـٰلَمِينَ","en":"And you will see the angels surrounding the Throne, exalting [Allāh] with praise of their Lord. And it will be judged between them in truth, and it will be said, \"[All] praise to Allāh, Lord of the worlds.\"","tr":"Watara almala-ikata haffeenamin hawli alAAarshi yusabbihoona bihamdirabbihim waqudiya baynahum bilhaqqi waqeelaalhamdu lillahi rabbi alAAalameen","juz":24,"page":467},{"s":40,"a":1,"key":"40:1","ar":" حمٓ","en":"Ḥā, Meem.1","tr":"Ha-meem","juz":24,"page":467},{"s":40,"a":2,"key":"40:2","ar":"تَنزِيلُ ٱلْكِتَـٰبِ مِنَ ٱللَّهِ ٱلْعَزِيزِ ٱلْعَلِيمِ","en":"The revelation of the Book [i.e., the Qur’ān] is from Allāh, the Exalted in Might, the Knowing,","tr":"Tanzeelu alkitabi mina AllahialAAazeezi alAAaleem","juz":24,"page":467},{"s":40,"a":3,"key":"40:3","ar":"غَافِرِ ٱلذَّنۢبِ وَقَابِلِ ٱلتَّوْبِ شَدِيدِ ٱلْعِقَابِ ذِى ٱلطَّوْلِ ۖ لَآ إِلَـٰهَ إِلَّا هُوَ ۖ إِلَيْهِ ٱلْمَصِيرُ","en":"The forgiver of sin, acceptor of repentance, severe in punishment, owner of abundance. There is no deity except Him; to Him is the destination.","tr":"Ghafiri aththanbi waqabiliattawbi shadeedi alAAiqabi thee attawlila ilaha illa huwa ilayhi almaseer","juz":24,"page":467},{"s":40,"a":4,"key":"40:4","ar":"مَا يُجَـٰدِلُ فِىٓ ءَايَـٰتِ ٱللَّهِ إِلَّا ٱلَّذِينَ كَفَرُوا۟ فَلَا يَغْرُرْكَ تَقَلُّبُهُمْ فِى ٱلْبِلَـٰدِ","en":"No one disputes concerning the signs of Allāh except those who disbelieve, so be not deceived by their [uninhibited] movement throughout the land.","tr":"Ma yujadilu fee ayatiAllahi illa allatheena kafaroo falayaghrurka taqallubuhum fee albilad","juz":24,"page":467},{"s":40,"a":5,"key":"40:5","ar":"كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍ وَٱلْأَحْزَابُ مِنۢ بَعْدِهِمْ ۖ وَهَمَّتْ كُلُّ أُمَّةٍۭ بِرَسُولِهِمْ لِيَأْخُذُوهُ ۖ وَجَـٰدَلُوا۟ بِٱلْبَـٰطِلِ لِيُدْحِضُوا۟ بِهِ ٱلْحَقَّ فَأَخَذْتُهُمْ ۖ فَكَيْفَ كَانَ عِقَابِ","en":"The people of Noah denied before them and the [disbelieving] factions after them, and every nation intended [a plot] for their messenger to seize him, and they disputed by [using] falsehood to [attempt to] invalidate thereby the truth. So I seized them, and how [terrible] was My penalty.","tr":"Kaththabat qablahum qawmu noohinwal-ahzabu min baAAdihim wahammat kulluommatin birasoolihim liya/khuthoohu wajadaloo bilbatililiyudhidoo bihi alhaqqa faakhathtuhumfakayfa kana AAiqab","juz":24,"page":467},{"s":40,"a":6,"key":"40:6","ar":"وَكَذَٰلِكَ حَقَّتْ كَلِمَتُ رَبِّكَ عَلَى ٱلَّذِينَ كَفَرُوٓا۟ أَنَّهُمْ أَصْحَـٰبُ ٱلنَّارِ","en":"And thus has the word [i.e., decree] of your Lord come into effect upon those who disbelieved that they are companions of the Fire.","tr":"Wakathalika haqqat kalimaturabbika AAala allatheena kafaroo annahum as-habuannar","juz":24,"page":467},{"s":40,"a":7,"key":"40:7","ar":"ٱلَّذِينَ يَحْمِلُونَ ٱلْعَرْشَ وَمَنْ حَوْلَهُۥ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْ وَيُؤْمِنُونَ بِهِۦ وَيَسْتَغْفِرُونَ لِلَّذِينَ ءَامَنُوا۟ رَبَّنَا وَسِعْتَ كُلَّ شَىْءٍ رَّحْمَةً وَعِلْمًا فَٱغْفِرْ لِلَّذِينَ تَابُوا۟ وَٱتَّبَعُوا۟ سَبِيلَكَ وَقِهِمْ عَذَابَ ٱلْجَحِيمِ","en":"Those [angels] who carry the Throne and those around it exalt [Allāh] with praise of their Lord and believe in Him and ask forgiveness for those who have believed, [saying], \"Our Lord, You have encompassed all things in mercy and knowledge, so forgive those who have repented and followed Your way and protect them from the punishment of Hellfire.","tr":"Allatheena yahmiloona alAAarshawaman hawlahu yusabbihoona bihamdi rabbihimwayu/minoona bihi wayastaghfiroona lillatheena amanoorabbana wasiAAta kulla shay-in rahmatan waAAilmanfaghfir lillatheena taboo wattabaAAoosabeelaka waqihim AAathaba aljaheem","juz":24,"page":467},{"s":40,"a":8,"key":"40:8","ar":"رَبَّنَا وَأَدْخِلْهُمْ جَنَّـٰتِ عَدْنٍ ٱلَّتِى وَعَدتَّهُمْ وَمَن صَلَحَ مِنْ ءَابَآئِهِمْ وَأَزْوَٰجِهِمْ وَذُرِّيَّـٰتِهِمْ ۚ إِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Our Lord, and admit them to gardens of perpetual residence which You have promised them and whoever was righteous among their forefathers, their spouses and their offspring. Indeed, it is You who is the Exalted in Might, the Wise.","tr":"Rabbana waadkhilhum jannatiAAadnin allatee waAAadtahum waman salaha min aba-ihimwaazwajihim wathurriyyatihim innaka antaalAAazeezu alhakeem","juz":24,"page":468},{"s":40,"a":9,"key":"40:9","ar":"وَقِهِمُ ٱلسَّيِّـَٔاتِ ۚ وَمَن تَقِ ٱلسَّيِّـَٔاتِ يَوْمَئِذٍ فَقَدْ رَحِمْتَهُۥ ۚ وَذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"And protect them from the evil consequences [of their deeds]. And he whom You protect from evil consequences that Day - You will have given him mercy. And that is the great attainment.\"","tr":"Waqihimu assayyi-ati wamantaqi assayyi-ati yawma-ithin faqad rahimtahuwathalika huwa alfawzu alAAatheem","juz":24,"page":468},{"s":40,"a":10,"key":"40:10","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ يُنَادَوْنَ لَمَقْتُ ٱللَّهِ أَكْبَرُ مِن مَّقْتِكُمْ أَنفُسَكُمْ إِذْ تُدْعَوْنَ إِلَى ٱلْإِيمَـٰنِ فَتَكْفُرُونَ","en":"Indeed, those who disbelieve will be addressed, \"The hatred of Allāh for you was [even] greater than your hatred of yourselves [this Day in Hell] when you were invited to faith, but you disbelieved [i.e., refused].\"","tr":"Inna allatheena kafaroo yunadawnalamaqtu Allahi akbaru min maqtikum anfusakum ithtudAAawna ila al-eemani fatakfuroon","juz":24,"page":468},{"s":40,"a":11,"key":"40:11","ar":"قَالُوا۟ رَبَّنَآ أَمَتَّنَا ٱثْنَتَيْنِ وَأَحْيَيْتَنَا ٱثْنَتَيْنِ فَٱعْتَرَفْنَا بِذُنُوبِنَا فَهَلْ إِلَىٰ خُرُوجٍ مِّن سَبِيلٍ","en":"They will say, \"Our Lord, You made us lifeless twice and gave us life twice, and we have confessed our sins. So is there to an exit any way?\"","tr":"Qaloo rabbana amattanaithnatayni waahyaytana ithnatayni faAAtarafnabithunoobina fahal ila khuroojin min sabeel","juz":24,"page":468},{"s":40,"a":12,"key":"40:12","ar":"ذَٰلِكُم بِأَنَّهُۥٓ إِذَا دُعِىَ ٱللَّهُ وَحْدَهُۥ كَفَرْتُمْ ۖ وَإِن يُشْرَكْ بِهِۦ تُؤْمِنُوا۟ ۚ فَٱلْحُكْمُ لِلَّهِ ٱلْعَلِىِّ ٱلْكَبِيرِ","en":"[They will be told], \"That is because, when Allāh was called upon alone, you disbelieved; but if others were associated with Him, you believed. So the judgement is with Allāh, the Most High, the Grand.\"","tr":"Thalikum bi-annahu ithaduAAiya Allahu wahdahu kafartum wa-in yushrak bihitu/minoo falhukmu lillahi alAAaliyyialkabeer","juz":24,"page":468},{"s":40,"a":13,"key":"40:13","ar":"هُوَ ٱلَّذِى يُرِيكُمْ ءَايَـٰتِهِۦ وَيُنَزِّلُ لَكُم مِّنَ ٱلسَّمَآءِ رِزْقًا ۚ وَمَا يَتَذَكَّرُ إِلَّا مَن يُنِيبُ","en":"It is He who shows you His signs and sends down to you from the sky, provision. But none will remember except he who turns back [in repentance].","tr":"Huwa allathee yureekum ayatihiwayunazzilu lakum mina assama-i rizqan wamayatathakkaru illa man yuneeb","juz":24,"page":468},{"s":40,"a":14,"key":"40:14","ar":"فَٱدْعُوا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ وَلَوْ كَرِهَ ٱلْكَـٰفِرُونَ","en":"So invoke Allāh, [being] sincere to Him in religion, although the disbelievers dislike it.","tr":"FadAAoo Allaha mukhliseenalahu addeena walaw kariha alkafiroon","juz":24,"page":468},{"s":40,"a":15,"key":"40:15","ar":"رَفِيعُ ٱلدَّرَجَـٰتِ ذُو ٱلْعَرْشِ يُلْقِى ٱلرُّوحَ مِنْ أَمْرِهِۦ عَلَىٰ مَن يَشَآءُ مِنْ عِبَادِهِۦ لِيُنذِرَ يَوْمَ ٱلتَّلَاقِ","en":"[He is] the Exalted above [all] degrees, Owner of the Throne; He places the inspiration of His command [i.e., revelation] upon whom He wills of His servants to warn of the Day of Meeting.","tr":"RafeeAAu addarajati thooalAAarshi yulqee arrooha min amrihi AAalaman yashao min AAibadihi liyunthira yawma attalaq","juz":24,"page":468},{"s":40,"a":16,"key":"40:16","ar":"يَوْمَ هُم بَـٰرِزُونَ ۖ لَا يَخْفَىٰ عَلَى ٱللَّهِ مِنْهُمْ شَىْءٌ ۚ لِّمَنِ ٱلْمُلْكُ ٱلْيَوْمَ ۖ لِلَّهِ ٱلْوَٰحِدِ ٱلْقَهَّارِ","en":"The Day they come forth nothing concerning them will be concealed from Allāh. To whom belongs [all] sovereignty this Day? To Allāh, the One, the Prevailing.1","tr":"Yawma hum barizoona la yakhfaAAala Allahi minhum shay-on limani almulku alyawmalillahi alwahidi alqahhar","juz":24,"page":468},{"s":40,"a":17,"key":"40:17","ar":"ٱلْيَوْمَ تُجْزَىٰ كُلُّ نَفْسٍۭ بِمَا كَسَبَتْ ۚ لَا ظُلْمَ ٱلْيَوْمَ ۚ إِنَّ ٱللَّهَ سَرِيعُ ٱلْحِسَابِ","en":"This Day every soul will be recompensed for what it earned. No injustice today! Indeed, Allāh is swift in account.","tr":"Alyawma tujza kullu nafsin bimakasabat la thulma alyawma inna AllahasareeAAu alhisab","juz":24,"page":469},{"s":40,"a":18,"key":"40:18","ar":"وَأَنذِرْهُمْ يَوْمَ ٱلْـَٔازِفَةِ إِذِ ٱلْقُلُوبُ لَدَى ٱلْحَنَاجِرِ كَـٰظِمِينَ ۚ مَا لِلظَّـٰلِمِينَ مِنْ حَمِيمٍ وَلَا شَفِيعٍ يُطَاعُ","en":"And warn them, [O Muḥammad], of the Approaching Day, when hearts are at the throats, filled [with distress]. For the wrongdoers there will be no devoted friend and no intercessor [who is] obeyed.","tr":"Waanthirhum yawma al-azifati ithialquloobu lada alhanajiri kathimeenama liththalimeena min hameeminwala shafeeAAin yutaAA","juz":24,"page":469},{"s":40,"a":19,"key":"40:19","ar":"يَعْلَمُ خَآئِنَةَ ٱلْأَعْيُنِ وَمَا تُخْفِى ٱلصُّدُورُ","en":"He knows that which deceives the eyes and what the breasts conceal.","tr":"YaAAlamu kha-inata al-aAAyuni wamatukhfee assudoor","juz":24,"page":469},{"s":40,"a":20,"key":"40:20","ar":"وَٱللَّهُ يَقْضِى بِٱلْحَقِّ ۖ وَٱلَّذِينَ يَدْعُونَ مِن دُونِهِۦ لَا يَقْضُونَ بِشَىْءٍ ۗ إِنَّ ٱللَّهَ هُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ","en":"And Allāh judges with truth, while those they invoke1 besides Him judge not with anything. Indeed, Allāh - He is the Hearing, the Seeing.","tr":"Wallahu yaqdee bilhaqqiwallatheena yadAAoona min doonihi la yaqdoonabishay-in inna Allaha huwa assameeAAu albaseer","juz":24,"page":469},{"s":40,"a":21,"key":"40:21","ar":"۞ أَوَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلَّذِينَ كَانُوا۟ مِن قَبْلِهِمْ ۚ كَانُوا۟ هُمْ أَشَدَّ مِنْهُمْ قُوَّةً وَءَاثَارًا فِى ٱلْأَرْضِ فَأَخَذَهُمُ ٱللَّهُ بِذُنُوبِهِمْ وَمَا كَانَ لَهُم مِّنَ ٱللَّهِ مِن وَاقٍ","en":"Have they not traveled through the land and observed how was the end of those who were before them? They were greater than them in strength and in impression on the land, but Allāh seized them for their sins. And they had not from Allāh any protector.","tr":"Awa lam yaseeroo fee al-ardi fayanthurookayfa kana AAaqibatu allatheena kanoomin qablihim kanoo hum ashadda minhum quwwatan waatharanfee al-ardi faakhathahumu Allahu bithunoobihimwama kana lahum mina Allahi min waq","juz":24,"page":469},{"s":40,"a":22,"key":"40:22","ar":"ذَٰلِكَ بِأَنَّهُمْ كَانَت تَّأْتِيهِمْ رُسُلُهُم بِٱلْبَيِّنَـٰتِ فَكَفَرُوا۟ فَأَخَذَهُمُ ٱللَّهُ ۚ إِنَّهُۥ قَوِىٌّ شَدِيدُ ٱلْعِقَابِ","en":"That was because their messengers were coming to them with clear proofs, but they disbelieved, so Allāh seized them. Indeed, He is Powerful and severe in punishment.","tr":"Thalika bi-annahum kanatta/teehim rusuluhum bilbayyinati fakafaroo faakhathahumuAllahu innahu qawiyyun shadeedu alAAiqab","juz":24,"page":469},{"s":40,"a":23,"key":"40:23","ar":"وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِـَٔايَـٰتِنَا وَسُلْطَـٰنٍ مُّبِينٍ","en":"And We did certainly send Moses with Our signs and a clear authority1","tr":"Walaqad arsalna moosa bi-ayatinawasultanin mubeen","juz":24,"page":469},{"s":40,"a":24,"key":"40:24","ar":"إِلَىٰ فِرْعَوْنَ وَهَـٰمَـٰنَ وَقَـٰرُونَ فَقَالُوا۟ سَـٰحِرٌ كَذَّابٌ","en":"To Pharaoh, Hāmān and Qārūn, but they said, \"[He is] a magician and a liar.\"","tr":"Ila firAAawna wahamanawaqaroona faqaloo sahirun kaththab","juz":24,"page":469},{"s":40,"a":25,"key":"40:25","ar":"فَلَمَّا جَآءَهُم بِٱلْحَقِّ مِنْ عِندِنَا قَالُوا۟ ٱقْتُلُوٓا۟ أَبْنَآءَ ٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ وَٱسْتَحْيُوا۟ نِسَآءَهُمْ ۚ وَمَا كَيْدُ ٱلْكَـٰفِرِينَ إِلَّا فِى ضَلَـٰلٍ","en":"And when he brought them the truth from Us, they said, \"Kill the sons of those who have believed with him and keep their women alive.\" But the plan of the disbelievers is not except in error.","tr":"Falamma jaahum bilhaqqimin AAindina qaloo oqtuloo abnaa allatheenaamanoo maAAahu wastahyoo nisaahumwama kaydu alkafireena illa fee dalal","juz":24,"page":469},{"s":40,"a":26,"key":"40:26","ar":"وَقَالَ فِرْعَوْنُ ذَرُونِىٓ أَقْتُلْ مُوسَىٰ وَلْيَدْعُ رَبَّهُۥٓ ۖ إِنِّىٓ أَخَافُ أَن يُبَدِّلَ دِينَكُمْ أَوْ أَن يُظْهِرَ فِى ٱلْأَرْضِ ٱلْفَسَادَ","en":"And Pharaoh said, \"Let me kill Moses and let him call upon his Lord. Indeed, I fear that he will change your religion or that he will cause corruption1 in the land.\"","tr":"Waqala firAAawnu tharooneeaqtul moosa walyadAAu rabbahu innee akhafu anyubaddila deenakum aw an yuthhira fee al-ardialfasad","juz":24,"page":470},{"s":40,"a":27,"key":"40:27","ar":"وَقَالَ مُوسَىٰٓ إِنِّى عُذْتُ بِرَبِّى وَرَبِّكُم مِّن كُلِّ مُتَكَبِّرٍ لَّا يُؤْمِنُ بِيَوْمِ ٱلْحِسَابِ","en":"But Moses said, \"Indeed, I have sought refuge in my Lord and your Lord from every arrogant one who does not believe in the Day of Account.\"","tr":"Waqala moosa innee AAuthtubirabbee warabbikum min kulli mutakabbirin la yu/minubiyawmi alhisab","juz":24,"page":470},{"s":40,"a":28,"key":"40:28","ar":"وَقَالَ رَجُلٌ مُّؤْمِنٌ مِّنْ ءَالِ فِرْعَوْنَ يَكْتُمُ إِيمَـٰنَهُۥٓ أَتَقْتُلُونَ رَجُلًا أَن يَقُولَ رَبِّىَ ٱللَّهُ وَقَدْ جَآءَكُم بِٱلْبَيِّنَـٰتِ مِن رَّبِّكُمْ ۖ وَإِن يَكُ كَـٰذِبًا فَعَلَيْهِ كَذِبُهُۥ ۖ وَإِن يَكُ صَادِقًا يُصِبْكُم بَعْضُ ٱلَّذِى يَعِدُكُمْ ۖ إِنَّ ٱللَّهَ لَا يَهْدِى مَنْ هُوَ مُسْرِفٌ كَذَّابٌ","en":"And a believing man from the family of Pharaoh who concealed his faith said, \"Do you kill a man [merely] because he says, 'My Lord is Allāh' while he has brought you clear proofs from your Lord? And if he should be lying, then upon him is [the consequence of] his lie; but if he should be truthful, there will strike you some of what he promises you. Indeed, Allāh does not guide one who is a transgressor and a liar.","tr":"Waqala rajulun mu/minun min alifirAAawna yaktumu eemanahu ataqtuloona rajulan an yaqoolarabbiyya Allahu waqad jaakum bilbayyinatimin rabbikum wa-in yaku kathiban faAAalayhi kathibuhuwa-in yaku sadiqan yusibkum baAAdu allatheeyaAAidukum inna Allaha la yahdee man huwa musrifunkaththab","juz":24,"page":470},{"s":40,"a":29,"key":"40:29","ar":"يَـٰقَوْمِ لَكُمُ ٱلْمُلْكُ ٱلْيَوْمَ ظَـٰهِرِينَ فِى ٱلْأَرْضِ فَمَن يَنصُرُنَا مِنۢ بَأْسِ ٱللَّهِ إِن جَآءَنَا ۚ قَالَ فِرْعَوْنُ مَآ أُرِيكُمْ إِلَّا مَآ أَرَىٰ وَمَآ أَهْدِيكُمْ إِلَّا سَبِيلَ ٱلرَّشَادِ","en":"O my people, sovereignty is yours today, [your being] dominant in the land. But who would protect us from the punishment of Allāh if it came to us?\" Pharaoh said, \"I do not show you except what I see, and I do not guide you except to the way of right conduct.\"","tr":"Ya qawmi lakumu almulku alyawma thahireenafee al-ardi faman yansuruna min ba/si Allahiin jaana qala firAAawnu ma oreekumilla ma ara wama ahdeekum illasabeela arrashad","juz":24,"page":470},{"s":40,"a":30,"key":"40:30","ar":"وَقَالَ ٱلَّذِىٓ ءَامَنَ يَـٰقَوْمِ إِنِّىٓ أَخَافُ عَلَيْكُم مِّثْلَ يَوْمِ ٱلْأَحْزَابِ","en":"And he who believed said, \"O my people, indeed I fear for you [a fate] like the day of the companies1 -","tr":"Waqala allathee amana yaqawmi innee akhafu AAalaykum mithla yawmi al-ahzab","juz":24,"page":470},{"s":40,"a":31,"key":"40:31","ar":"مِثْلَ دَأْبِ قَوْمِ نُوحٍ وَعَادٍ وَثَمُودَ وَٱلَّذِينَ مِنۢ بَعْدِهِمْ ۚ وَمَا ٱللَّهُ يُرِيدُ ظُلْمًا لِّلْعِبَادِ","en":"Like the custom of the people of Noah and of ʿAad and Thamūd and those after them. And Allāh wants no injustice for [His] servants.","tr":"Mithla da/bi qawmi noohin waAAadinwathamooda wallatheena min baAAdihim wamaAllahu yureedu thulman lilAAibad","juz":24,"page":470},{"s":40,"a":32,"key":"40:32","ar":"وَيَـٰقَوْمِ إِنِّىٓ أَخَافُ عَلَيْكُمْ يَوْمَ ٱلتَّنَادِ","en":"And O my people, indeed I fear for you the Day of Calling1 -","tr":"Waya qawmi innee akhafuAAalaykum yawma attanad","juz":24,"page":470},{"s":40,"a":33,"key":"40:33","ar":"يَوْمَ تُوَلُّونَ مُدْبِرِينَ مَا لَكُم مِّنَ ٱللَّهِ مِنْ عَاصِمٍ ۗ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِنْ هَادٍ","en":"The Day you will turn your backs fleeing; there is not for you from Allāh any protector. And whoever Allāh sends astray - there is not for him any guide.","tr":"Yawma tuwalloona mudbireena ma lakummina Allahi min AAasimin waman yudlili Allahufama lahu min had","juz":24,"page":470},{"s":40,"a":34,"key":"40:34","ar":"وَلَقَدْ جَآءَكُمْ يُوسُفُ مِن قَبْلُ بِٱلْبَيِّنَـٰتِ فَمَا زِلْتُمْ فِى شَكٍّ مِّمَّا جَآءَكُم بِهِۦ ۖ حَتَّىٰٓ إِذَا هَلَكَ قُلْتُمْ لَن يَبْعَثَ ٱللَّهُ مِنۢ بَعْدِهِۦ رَسُولًا ۚ كَذَٰلِكَ يُضِلُّ ٱللَّهُ مَنْ هُوَ مُسْرِفٌ مُّرْتَابٌ","en":"And Joseph had already come to you before with clear proofs, but you remained in doubt of that which he brought to you, until when he died, you said, 'Never will Allāh send a messenger after him.' Thus does Allāh leave astray he who is a transgressor and skeptic.\"","tr":"Walaqad jaakum yoosufu min qablu bilbayyinatifama ziltum fee shakkin mimma jaakum bihi hattaitha halaka qultum lan yabAAatha Allahu minbaAAdihi rasoolan kathalika yudillu Allahuman huwa musrifun murtab","juz":24,"page":471},{"s":40,"a":35,"key":"40:35","ar":"ٱلَّذِينَ يُجَـٰدِلُونَ فِىٓ ءَايَـٰتِ ٱللَّهِ بِغَيْرِ سُلْطَـٰنٍ أَتَىٰهُمْ ۖ كَبُرَ مَقْتًا عِندَ ٱللَّهِ وَعِندَ ٱلَّذِينَ ءَامَنُوا۟ ۚ كَذَٰلِكَ يَطْبَعُ ٱللَّهُ عَلَىٰ كُلِّ قَلْبِ مُتَكَبِّرٍ جَبَّارٍ","en":"Those who dispute concerning the signs of Allāh without an authority1 having come to them - great is hatred [of them] in the sight of Allāh and in the sight of those who have believed. Thus does Allāh seal over every heart [belonging to] an arrogant tyrant.","tr":"Allatheena yujadiloona fee ayatiAllahi bighayri sultanin atahum kaburamaqtan AAinda Allahi waAAinda allatheena amanookathalika yatbaAAu Allahu AAala kulliqalbi mutakabbirin jabbar","juz":24,"page":471},{"s":40,"a":36,"key":"40:36","ar":"وَقَالَ فِرْعَوْنُ يَـٰهَـٰمَـٰنُ ٱبْنِ لِى صَرْحًا لَّعَلِّىٓ أَبْلُغُ ٱلْأَسْبَـٰبَ","en":"And Pharaoh said, \"O Hāmān, construct for me a tower that I might reach the ways1 -","tr":"Waqala firAAawnu ya hamanuibni lee sarhan laAAallee ablughu al-asbab","juz":24,"page":471},{"s":40,"a":37,"key":"40:37","ar":"أَسْبَـٰبَ ٱلسَّمَـٰوَٰتِ فَأَطَّلِعَ إِلَىٰٓ إِلَـٰهِ مُوسَىٰ وَإِنِّى لَأَظُنُّهُۥ كَـٰذِبًا ۚ وَكَذَٰلِكَ زُيِّنَ لِفِرْعَوْنَ سُوٓءُ عَمَلِهِۦ وَصُدَّ عَنِ ٱلسَّبِيلِ ۚ وَمَا كَيْدُ فِرْعَوْنَ إِلَّا فِى تَبَابٍ","en":"The ways into the heavens - so that I may look at the deity of Moses; but indeed, I think he is a liar.\" And thus was made attractive to Pharaoh the evil of his deed, and he was averted from the [right] way. And the plan of Pharaoh was not except in ruin.","tr":"Asbaba assamawatifaattaliAAa ila ilahi moosa wa-inneelaathunnuhu kathiban wakathalikazuyyina lifirAAawna soo-o AAamalihi wasudda AAani assabeeliwama kaydu firAAawna illa fee tabab","juz":24,"page":471},{"s":40,"a":38,"key":"40:38","ar":"وَقَالَ ٱلَّذِىٓ ءَامَنَ يَـٰقَوْمِ ٱتَّبِعُونِ أَهْدِكُمْ سَبِيلَ ٱلرَّشَادِ","en":"And he who believed said, \"O my people, follow me; I will guide you to the way of right conduct.","tr":"Waqala allathee amana yaqawmi ittabiAAooni ahdikum sabeela arrashad","juz":24,"page":471},{"s":40,"a":39,"key":"40:39","ar":"يَـٰقَوْمِ إِنَّمَا هَـٰذِهِ ٱلْحَيَوٰةُ ٱلدُّنْيَا مَتَـٰعٌ وَإِنَّ ٱلْـَٔاخِرَةَ هِىَ دَارُ ٱلْقَرَارِ","en":"O my people, this worldly life is only [temporary] enjoyment, and indeed, the Hereafter - that is the home of [permanent] settlement.","tr":"Ya qawmi innama hathihialhayatu addunya mataAAunwa-inna al-akhirata hiya daru alqarar","juz":24,"page":471},{"s":40,"a":40,"key":"40:40","ar":"مَنْ عَمِلَ سَيِّئَةً فَلَا يُجْزَىٰٓ إِلَّا مِثْلَهَا ۖ وَمَنْ عَمِلَ صَـٰلِحًا مِّن ذَكَرٍ أَوْ أُنثَىٰ وَهُوَ مُؤْمِنٌ فَأُو۟لَـٰٓئِكَ يَدْخُلُونَ ٱلْجَنَّةَ يُرْزَقُونَ فِيهَا بِغَيْرِ حِسَابٍ","en":"Whoever does an evil deed will not be recompensed except by the like thereof; but whoever does righteousness, whether male or female, while he is a believer - those will enter Paradise, being given provision therein without account.","tr":"Man AAamila sayyi-atan fala yujzailla mithlaha waman AAamila salihanmin thakarin aw ontha wahuwa mu/minun faola-ikayadkhuloona aljannata yurzaqoona feeha bighayri hisab","juz":24,"page":471},{"s":40,"a":41,"key":"40:41","ar":"۞ وَيَـٰقَوْمِ مَا لِىٓ أَدْعُوكُمْ إِلَى ٱلنَّجَوٰةِ وَتَدْعُونَنِىٓ إِلَى ٱلنَّارِ","en":"And O my people, how is it that I invite you to salvation while you invite me to the Fire?","tr":"Waya qawmi malee adAAookum ilaannajati watadAAoonanee ila annar","juz":24,"page":472},{"s":40,"a":42,"key":"40:42","ar":"تَدْعُونَنِى لِأَكْفُرَ بِٱللَّهِ وَأُشْرِكَ بِهِۦ مَا لَيْسَ لِى بِهِۦ عِلْمٌ وَأَنَا۠ أَدْعُوكُمْ إِلَى ٱلْعَزِيزِ ٱلْغَفَّـٰرِ","en":"You invite me to disbelieve in Allāh and associate with Him that of which I have no knowledge, and I invite you to the Exalted in Might, the Perpetual Forgiver.1","tr":"TadAAoonanee li-akfura billahiwaoshrika bihi ma laysa lee bihi AAilmun waanaadAAookum ila alAAazeezi alghaffar","juz":24,"page":472},{"s":40,"a":43,"key":"40:43","ar":"لَا جَرَمَ أَنَّمَا تَدْعُونَنِىٓ إِلَيْهِ لَيْسَ لَهُۥ دَعْوَةٌ فِى ٱلدُّنْيَا وَلَا فِى ٱلْـَٔاخِرَةِ وَأَنَّ مَرَدَّنَآ إِلَى ٱللَّهِ وَأَنَّ ٱلْمُسْرِفِينَ هُمْ أَصْحَـٰبُ ٱلنَّارِ","en":"Assuredly, that to which you invite me has no [response to a] supplication in this world or in the Hereafter; and indeed, our return is to Allāh, and indeed, the transgressors will be companions of the Fire.","tr":"La jarama annama tadAAoonaneeilayhi laysa lahu daAAwatun fee addunya walafee al-akhirati waanna maraddana ila Allahiwaanna almusrifeena hum as-habu annar","juz":24,"page":472},{"s":40,"a":44,"key":"40:44","ar":"فَسَتَذْكُرُونَ مَآ أَقُولُ لَكُمْ ۚ وَأُفَوِّضُ أَمْرِىٓ إِلَى ٱللَّهِ ۚ إِنَّ ٱللَّهَ بَصِيرٌۢ بِٱلْعِبَادِ","en":"And you will remember what I [now] say to you, and I entrust my affair to Allāh. Indeed, Allāh is Seeing of [His] servants.\"","tr":"Fasatathkuroona ma aqoolulakum waofawwidu amree ila Allahi inna Allahabaseerun bilAAibad","juz":24,"page":472},{"s":40,"a":45,"key":"40:45","ar":"فَوَقَىٰهُ ٱللَّهُ سَيِّـَٔاتِ مَا مَكَرُوا۟ ۖ وَحَاقَ بِـَٔالِ فِرْعَوْنَ سُوٓءُ ٱلْعَذَابِ","en":"So Allāh protected him from the evils they plotted, and the people of Pharaoh were enveloped by the worst of punishment -","tr":"Fawaqahu Allahu sayyi-atima makaroo wahaqa bi-ali firAAawna soo-oalAAathab","juz":24,"page":472},{"s":40,"a":46,"key":"40:46","ar":"ٱلنَّارُ يُعْرَضُونَ عَلَيْهَا غُدُوًّا وَعَشِيًّا ۖ وَيَوْمَ تَقُومُ ٱلسَّاعَةُ أَدْخِلُوٓا۟ ءَالَ فِرْعَوْنَ أَشَدَّ ٱلْعَذَابِ","en":"The Fire; they are exposed to it morning and evening.1 And the Day the Hour appears [it will be said], \"Make the people of Pharaoh enter the severest punishment.\"","tr":"Annaru yuAAradoonaAAalayha ghuduwwan waAAashiyyan wayawma taqoomu assaAAatuadkhiloo ala firAAawna ashadda alAAathab","juz":24,"page":472},{"s":40,"a":47,"key":"40:47","ar":"وَإِذْ يَتَحَآجُّونَ فِى ٱلنَّارِ فَيَقُولُ ٱلضُّعَفَـٰٓؤُا۟ لِلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا كُنَّا لَكُمْ تَبَعًا فَهَلْ أَنتُم مُّغْنُونَ عَنَّا نَصِيبًا مِّنَ ٱلنَّارِ","en":"And [mention] when they will argue within the Fire, and the weak will say to those who had been arrogant, \"Indeed, we were [only] your followers, so will you relieve us of a share of the Fire?\"","tr":"Wa-ith yatahajjoona fee annarifayaqoolu adduAAafao lillatheenaistakbaroo inna kunna lakum tabaAAan fahal antummughnoona AAanna naseeban mina annar","juz":24,"page":472},{"s":40,"a":48,"key":"40:48","ar":"قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوٓا۟ إِنَّا كُلٌّ فِيهَآ إِنَّ ٱللَّهَ قَدْ حَكَمَ بَيْنَ ٱلْعِبَادِ","en":"Those who had been arrogant will say, \"Indeed, all [of us] are in it. Indeed, Allāh has judged between the servants.\"","tr":"Qala allatheena istakbaroo innakullun feeha inna Allaha qad hakama baynaalAAibad","juz":24,"page":472},{"s":40,"a":49,"key":"40:49","ar":"وَقَالَ ٱلَّذِينَ فِى ٱلنَّارِ لِخَزَنَةِ جَهَنَّمَ ٱدْعُوا۟ رَبَّكُمْ يُخَفِّفْ عَنَّا يَوْمًا مِّنَ ٱلْعَذَابِ","en":"And those in the Fire will say to the keepers of Hell, \"Supplicate your Lord to lighten for us a day from the punishment.\"","tr":"Waqala allatheena fee annarilikhazanati jahannama odAAoo rabbakum yukhaffif AAannayawman mina alAAathab","juz":24,"page":472},{"s":40,"a":50,"key":"40:50","ar":"قَالُوٓا۟ أَوَلَمْ تَكُ تَأْتِيكُمْ رُسُلُكُم بِٱلْبَيِّنَـٰتِ ۖ قَالُوا۟ بَلَىٰ ۚ قَالُوا۟ فَٱدْعُوا۟ ۗ وَمَا دُعَـٰٓؤُا۟ ٱلْكَـٰفِرِينَ إِلَّا فِى ضَلَـٰلٍ","en":"They will say, \"Did there not come to you your messengers with clear proofs?\" They will say, \"Yes.\" They will reply, \"Then supplicate [yourselves], but the supplication of the disbelievers is not except in error [i.e., futility].\"","tr":"Qaloo awa lam taku ta/teekumrusulukum bilbayyinati qaloo bala qaloofadAAoo wama duAAao alkafireena illafee dalal","juz":24,"page":473},{"s":40,"a":51,"key":"40:51","ar":"إِنَّا لَنَنصُرُ رُسُلَنَا وَٱلَّذِينَ ءَامَنُوا۟ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَيَوْمَ يَقُومُ ٱلْأَشْهَـٰدُ","en":"Indeed, We will support Our messengers and those who believe during the life of this world and on the Day when the witnesses will stand -","tr":"Inna lanansuru rusulanawallatheena amanoo fee alhayatiaddunya wayawma yaqoomu al-ashhad","juz":24,"page":473},{"s":40,"a":52,"key":"40:52","ar":"يَوْمَ لَا يَنفَعُ ٱلظَّـٰلِمِينَ مَعْذِرَتُهُمْ ۖ وَلَهُمُ ٱللَّعْنَةُ وَلَهُمْ سُوٓءُ ٱلدَّارِ","en":"The Day their excuse will not benefit the wrongdoers, and they will have the curse, and they will have the worst home [i.e., Hell].","tr":"Yawma la yanfaAAu aththalimeenamaAAthiratuhum walahumu allaAAnatu walahum soo-o addar","juz":24,"page":473},{"s":40,"a":53,"key":"40:53","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْهُدَىٰ وَأَوْرَثْنَا بَنِىٓ إِسْرَٰٓءِيلَ ٱلْكِتَـٰبَ","en":"And We had certainly given Moses guidance, and We caused the Children of Israel to inherit the Scripture","tr":"Walaqad atayna moosaalhuda waawrathna banee isra-eela alkitab","juz":24,"page":473},{"s":40,"a":54,"key":"40:54","ar":"هُدًى وَذِكْرَىٰ لِأُو۟لِى ٱلْأَلْبَـٰبِ","en":"As guidance and a reminder for those of understanding.","tr":"Hudan wathikra li-olee al-albab","juz":24,"page":473},{"s":40,"a":55,"key":"40:55","ar":"فَٱصْبِرْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ وَٱسْتَغْفِرْ لِذَنۢبِكَ وَسَبِّحْ بِحَمْدِ رَبِّكَ بِٱلْعَشِىِّ وَٱلْإِبْكَـٰرِ","en":"So be patient, [O Muḥammad]. Indeed, the promise of Allāh is truth. And ask forgiveness for your sin1 and exalt [Allāh] with praise of your Lord in the evening and the morning.","tr":"Fasbir inna waAAda Allahihaqqun wastaghfir lithanbika wasabbihbihamdi rabbika bilAAashiyyi wal-ibkar","juz":24,"page":473},{"s":40,"a":56,"key":"40:56","ar":"إِنَّ ٱلَّذِينَ يُجَـٰدِلُونَ فِىٓ ءَايَـٰتِ ٱللَّهِ بِغَيْرِ سُلْطَـٰنٍ أَتَىٰهُمْ ۙ إِن فِى صُدُورِهِمْ إِلَّا كِبْرٌ مَّا هُم بِبَـٰلِغِيهِ ۚ فَٱسْتَعِذْ بِٱللَّهِ ۖ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ","en":"Indeed, those who dispute concerning the signs of Allāh without [any] evidence having come to them - there is not within their breasts except pride, [the extent of] which they cannot reach. So seek refuge in Allāh. Indeed, it is He who is the Hearing, the Seeing.","tr":"Inna allatheena yujadiloonafee ayati Allahi bighayri sultanin atahumin fee sudoorihim illa kibrun ma hum bibaligheehifastaAAith billahi innahu huwa assameeAAualbaseer","juz":24,"page":473},{"s":40,"a":57,"key":"40:57","ar":"لَخَلْقُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ أَكْبَرُ مِنْ خَلْقِ ٱلنَّاسِ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"The creation of the heavens and earth is greater than the creation of mankind, but most of the people do not know.","tr":"Lakhalqu assamawati wal-ardiakbaru min khalqi annasi walakinna aktharaannasi la yaAAlamoon","juz":24,"page":473},{"s":40,"a":58,"key":"40:58","ar":"وَمَا يَسْتَوِى ٱلْأَعْمَىٰ وَٱلْبَصِيرُ وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ وَلَا ٱلْمُسِىٓءُ ۚ قَلِيلًا مَّا تَتَذَكَّرُونَ","en":"And not equal are the blind and the seeing, nor are those who believe and do righteous deeds and the evildoer. Little do you remember.","tr":"Wama yastawee al-aAAma walbaseeruwallatheena amanoo waAAamiloo assalihatiwala almusee-o qaleelan ma tatathakkaroon","juz":24,"page":473},{"s":40,"a":59,"key":"40:59","ar":"إِنَّ ٱلسَّاعَةَ لَـَٔاتِيَةٌ لَّا رَيْبَ فِيهَا وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يُؤْمِنُونَ","en":"Indeed, the Hour is coming - no doubt about it - but most of the people do not believe.","tr":"Inna assaAAata laatiyatunla rayba feeha walakinna akthara annasila yu/minoon","juz":24,"page":474},{"s":40,"a":60,"key":"40:60","ar":"وَقَالَ رَبُّكُمُ ٱدْعُونِىٓ أَسْتَجِبْ لَكُمْ ۚ إِنَّ ٱلَّذِينَ يَسْتَكْبِرُونَ عَنْ عِبَادَتِى سَيَدْخُلُونَ جَهَنَّمَ دَاخِرِينَ","en":"And your Lord says, \"Call upon Me; I will respond to you.\" Indeed, those who disdain My worship will enter Hell [rendered] contemptible.","tr":"Waqala rabbukumu odAAoonee astajiblakum inna allatheena yastakbiroona AAan AAibadateesayadkhuloona jahannama dakhireen","juz":24,"page":474},{"s":40,"a":61,"key":"40:61","ar":"ٱللَّهُ ٱلَّذِى جَعَلَ لَكُمُ ٱلَّيْلَ لِتَسْكُنُوا۟ فِيهِ وَٱلنَّهَارَ مُبْصِرًا ۚ إِنَّ ٱللَّهَ لَذُو فَضْلٍ عَلَى ٱلنَّاسِ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَشْكُرُونَ","en":"It is Allāh who made for you the night that you may rest therein and the day giving sight.1 Indeed, Allāh is the possessor of bounty for the people, but most of them are not grateful.","tr":"Allahu allathee jaAAala lakumuallayla litaskunoo feehi wannahara mubsiraninna Allaha lathoo fadlin AAala annasiwalakinna akthara annasi layashkuroon","juz":24,"page":474},{"s":40,"a":62,"key":"40:62","ar":"ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ خَـٰلِقُ كُلِّ شَىْءٍ لَّآ إِلَـٰهَ إِلَّا هُوَ ۖ فَأَنَّىٰ تُؤْفَكُونَ","en":"That is Allāh, your Lord, Creator of all things; there is no deity except Him, so how are you deluded?","tr":"Thalikumu Allahu rabbukum khaliqukulli shay-in la ilaha illa huwa faannatu/fakoon","juz":24,"page":474},{"s":40,"a":63,"key":"40:63","ar":"كَذَٰلِكَ يُؤْفَكُ ٱلَّذِينَ كَانُوا۟ بِـَٔايَـٰتِ ٱللَّهِ يَجْحَدُونَ","en":"Thus were those [before you] deluded who were rejecting the signs of Allāh.","tr":"Kathalika yu/faku allatheena kanoobi-ayati Allahi yajhadoon","juz":24,"page":474},{"s":40,"a":64,"key":"40:64","ar":"ٱللَّهُ ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ قَرَارًا وَٱلسَّمَآءَ بِنَآءً وَصَوَّرَكُمْ فَأَحْسَنَ صُوَرَكُمْ وَرَزَقَكُم مِّنَ ٱلطَّيِّبَـٰتِ ۚ ذَٰلِكُمُ ٱللَّهُ رَبُّكُمْ ۖ فَتَبَارَكَ ٱللَّهُ رَبُّ ٱلْعَـٰلَمِينَ","en":"It is Allāh who made for you the earth a place of settlement and the sky a structure [i.e., ceiling] and formed you and perfected your forms and provided you with good things. That is Allāh, your Lord; then blessed is Allāh, Lord of the worlds.","tr":"Allahu allathee jaAAala lakumual-arda qararan wassamaa binaanwasawwarakum faahsana suwarakum warazaqakummina attayyibati thalikumu Allahurabbukum fatabaraka Allahu rabbu alAAalameen","juz":24,"page":474},{"s":40,"a":65,"key":"40:65","ar":"هُوَ ٱلْحَىُّ لَآ إِلَـٰهَ إِلَّا هُوَ فَٱدْعُوهُ مُخْلِصِينَ لَهُ ٱلدِّينَ ۗ ٱلْحَمْدُ لِلَّهِ رَبِّ ٱلْعَـٰلَمِينَ","en":"He is the Ever-Living;1 there is no deity except Him, so call upon Him, [being] sincere to Him in religion. [All] praise is [due] to Allāh, Lord of the worlds.","tr":"Huwa alhayyu la ilahailla huwa fadAAoohu mukhliseena lahu addeenaalhamdu lillahi rabbi alAAalameen","juz":24,"page":474},{"s":40,"a":66,"key":"40:66","ar":"۞ قُلْ إِنِّى نُهِيتُ أَنْ أَعْبُدَ ٱلَّذِينَ تَدْعُونَ مِن دُونِ ٱللَّهِ لَمَّا جَآءَنِىَ ٱلْبَيِّنَـٰتُ مِن رَّبِّى وَأُمِرْتُ أَنْ أُسْلِمَ لِرَبِّ ٱلْعَـٰلَمِينَ","en":"Say, [O Muḥammad], \"Indeed, I have been forbidden to worship those you call upon besides Allāh once the clear proofs have come to me from my Lord, and I have been commanded to submit to the Lord of the worlds.\"","tr":"Qul innee nuheetu an aAAbuda allatheenatadAAoona min dooni Allahi lamma jaaniyaalbayyinatu min rabbee waomirtu an oslima lirabbi alAAalameen","juz":24,"page":474},{"s":40,"a":67,"key":"40:67","ar":"هُوَ ٱلَّذِى خَلَقَكُم مِّن تُرَابٍ ثُمَّ مِن نُّطْفَةٍ ثُمَّ مِنْ عَلَقَةٍ ثُمَّ يُخْرِجُكُمْ طِفْلًا ثُمَّ لِتَبْلُغُوٓا۟ أَشُدَّكُمْ ثُمَّ لِتَكُونُوا۟ شُيُوخًا ۚ وَمِنكُم مَّن يُتَوَفَّىٰ مِن قَبْلُ ۖ وَلِتَبْلُغُوٓا۟ أَجَلًا مُّسَمًّى وَلَعَلَّكُمْ تَعْقِلُونَ","en":"It is He who created you from dust, then from a sperm-drop, then from a clinging clot; then He brings you out as a child; then [He develops you] that you reach your [time of] maturity, then [further] that you become elders. And among you is he who is taken in death before [that], so that you reach a specified term;1 and perhaps you will use reason.","tr":"Huwa allathee khalaqakum min turabinthumma min nutfatin thumma min AAalaqatin thummayukhrijukum tiflan thumma litablughoo ashuddakum thummalitakoonoo shuyookhan waminkum man yutawaffa min qabluwalitablughoo ajalan musamman walaAAallakum taAAqiloon","juz":24,"page":475},{"s":40,"a":68,"key":"40:68","ar":"هُوَ ٱلَّذِى يُحْىِۦ وَيُمِيتُ ۖ فَإِذَا قَضَىٰٓ أَمْرًا فَإِنَّمَا يَقُولُ لَهُۥ كُن فَيَكُونُ","en":"He it is who gives life and causes death; and when He decrees a matter, He but says to it, \"Be,\" and it is.","tr":"Huwa allathee yuhyee wayumeetufa-itha qada amran fa-innama yaqoolu lahukun fayakoon","juz":24,"page":475},{"s":40,"a":69,"key":"40:69","ar":"أَلَمْ تَرَ إِلَى ٱلَّذِينَ يُجَـٰدِلُونَ فِىٓ ءَايَـٰتِ ٱللَّهِ أَنَّىٰ يُصْرَفُونَ","en":"Do you not consider those who dispute concerning the signs of Allāh - how are they averted?","tr":"Alam tara ila allatheena yujadiloonafee ayati Allahi anna yusrafoon","juz":24,"page":475},{"s":40,"a":70,"key":"40:70","ar":"ٱلَّذِينَ كَذَّبُوا۟ بِٱلْكِتَـٰبِ وَبِمَآ أَرْسَلْنَا بِهِۦ رُسُلَنَا ۖ فَسَوْفَ يَعْلَمُونَ","en":"Those who deny the Book [i.e., the Qur’ān] and that with which We sent Our messengers - they are going to know,","tr":"Allatheena kaththaboo bilkitabiwabima arsalna bihi rusulana fasawfayaAAlamoon","juz":24,"page":475},{"s":40,"a":71,"key":"40:71","ar":"إِذِ ٱلْأَغْلَـٰلُ فِىٓ أَعْنَـٰقِهِمْ وَٱلسَّلَـٰسِلُ يُسْحَبُونَ","en":"When the shackles are around their necks and the chains; they will be dragged","tr":"Ithi al-aghlalu fee aAAnaqihimwassalasilu yushaboon","juz":24,"page":475},{"s":40,"a":72,"key":"40:72","ar":"فِى ٱلْحَمِيمِ ثُمَّ فِى ٱلنَّارِ يُسْجَرُونَ","en":"In boiling water; then in the Fire they will be filled [with flame].","tr":"Fee alhameemi thumma fee annariyusjaroon","juz":24,"page":475},{"s":40,"a":73,"key":"40:73","ar":"ثُمَّ قِيلَ لَهُمْ أَيْنَ مَا كُنتُمْ تُشْرِكُونَ","en":"Then it will be said to them, \"Where is that which you used to associate [with Him in worship]","tr":"Thumma qeela lahum ayna ma kuntumtushrikoon","juz":24,"page":475},{"s":40,"a":74,"key":"40:74","ar":"مِن دُونِ ٱللَّهِ ۖ قَالُوا۟ ضَلُّوا۟ عَنَّا بَل لَّمْ نَكُن نَّدْعُوا۟ مِن قَبْلُ شَيْـًٔا ۚ كَذَٰلِكَ يُضِلُّ ٱللَّهُ ٱلْكَـٰفِرِينَ","en":"Other than Allāh?\" They will say, \"They have departed from us; rather, we did not used to invoke previously anything.\" Thus does Allāh put astray the disbelievers.","tr":"Min dooni Allahi qaloo dallooAAanna bal lam nakun nadAAoo min qablu shay-an kathalikayudillu Allahu alkafireen","juz":24,"page":475},{"s":40,"a":75,"key":"40:75","ar":"ذَٰلِكُم بِمَا كُنتُمْ تَفْرَحُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَبِمَا كُنتُمْ تَمْرَحُونَ","en":"[The angels will say], \"That was because you used to exult upon the earth without right and you used to behave insolently.","tr":"Thalikum bima kuntum tafrahoonafee al-ardi bighayri alhaqqi wabima kuntumtamrahoon","juz":24,"page":475},{"s":40,"a":76,"key":"40:76","ar":"ٱدْخُلُوٓا۟ أَبْوَٰبَ جَهَنَّمَ خَـٰلِدِينَ فِيهَا ۖ فَبِئْسَ مَثْوَى ٱلْمُتَكَبِّرِينَ","en":"Enter the gates of Hell to abide eternally therein, and wretched is the residence of the arrogant.\"","tr":"Odkhuloo abwaba jahannama khalideenafeeha fabi/sa mathwa almutakabbireen","juz":24,"page":475},{"s":40,"a":77,"key":"40:77","ar":"فَٱصْبِرْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ ۚ فَإِمَّا نُرِيَنَّكَ بَعْضَ ٱلَّذِى نَعِدُهُمْ أَوْ نَتَوَفَّيَنَّكَ فَإِلَيْنَا يُرْجَعُونَ","en":"So be patient, [O Muḥammad]; indeed, the promise of Allāh is truth. And whether We show you some of what We have promised them or We take you in death, it is to Us they will be returned.","tr":"Fasbir inna waAAda Allahihaqqun fa-imma nuriyannaka baAAda allatheenaAAiduhum aw natawaffayannaka fa-ilayna yurjaAAoon","juz":24,"page":475},{"s":40,"a":78,"key":"40:78","ar":"وَلَقَدْ أَرْسَلْنَا رُسُلًا مِّن قَبْلِكَ مِنْهُم مَّن قَصَصْنَا عَلَيْكَ وَمِنْهُم مَّن لَّمْ نَقْصُصْ عَلَيْكَ ۗ وَمَا كَانَ لِرَسُولٍ أَن يَأْتِىَ بِـَٔايَةٍ إِلَّا بِإِذْنِ ٱللَّهِ ۚ فَإِذَا جَآءَ أَمْرُ ٱللَّهِ قُضِىَ بِٱلْحَقِّ وَخَسِرَ هُنَالِكَ ٱلْمُبْطِلُونَ","en":"And We have already sent messengers before you. Among them are those [whose stories] We have related to you, and among them are those [whose stories] We have not related to you. And it was not for any messenger to bring a sign [or verse] except by permission of Allāh. So when the command of Allāh comes, it will be concluded [i.e., judged] in truth, and the falsifiers will thereupon lose [all].","tr":"Walaqad arsalna rusulan min qablikaminhum man qasasna AAalayka waminhum man lamnaqsus AAalayka wama kana lirasoolinan ya/tiya bi-ayatin illa bi-ithni Allahifa-itha jaa amru Allahi qudiya bilhaqqiwakhasira hunalika almubtiloon","juz":24,"page":476},{"s":40,"a":79,"key":"40:79","ar":"ٱللَّهُ ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَنْعَـٰمَ لِتَرْكَبُوا۟ مِنْهَا وَمِنْهَا تَأْكُلُونَ","en":"It is Allāh who made for you the grazing animals upon which you ride, and some of them you eat.","tr":"Allahu allathee jaAAala lakumual-anAAama litarkaboo minha waminhata/kuloon","juz":24,"page":476},{"s":40,"a":80,"key":"40:80","ar":"وَلَكُمْ فِيهَا مَنَـٰفِعُ وَلِتَبْلُغُوا۟ عَلَيْهَا حَاجَةً فِى صُدُورِكُمْ وَعَلَيْهَا وَعَلَى ٱلْفُلْكِ تُحْمَلُونَ","en":"And for you therein are [other] benefits and that you may realize upon them a need which is in your breasts;1 and upon them and upon ships you are carried.","tr":"Walakum feeha manafiAAuwalitablughoo AAalayha hajatan fee sudoorikumwaAAalayha waAAala alfulki tuhmaloon","juz":24,"page":476},{"s":40,"a":81,"key":"40:81","ar":"وَيُرِيكُمْ ءَايَـٰتِهِۦ فَأَىَّ ءَايَـٰتِ ٱللَّهِ تُنكِرُونَ","en":"And He shows you His signs. So which of the signs of Allāh do you deny?","tr":"Wayureekum ayatihi faayya ayatiAllahi tunkiroon","juz":24,"page":476},{"s":40,"a":82,"key":"40:82","ar":"أَفَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ كَانُوٓا۟ أَكْثَرَ مِنْهُمْ وَأَشَدَّ قُوَّةً وَءَاثَارًا فِى ٱلْأَرْضِ فَمَآ أَغْنَىٰ عَنْهُم مَّا كَانُوا۟ يَكْسِبُونَ","en":"Have they not traveled through the land and observed how was the end of those before them? They were more numerous than themselves and greater in strength and in impression on the land, but they were not availed by what they used to earn.","tr":"Afalam yaseeroo fee al-ardi fayanthurookayfa kana AAaqibatu allatheena min qablihimkanoo akthara minhum waashadda quwwatan waatharanfee al-ardi fama aghna AAanhum ma kanooyaksiboon","juz":24,"page":476},{"s":40,"a":83,"key":"40:83","ar":"فَلَمَّا جَآءَتْهُمْ رُسُلُهُم بِٱلْبَيِّنَـٰتِ فَرِحُوا۟ بِمَا عِندَهُم مِّنَ ٱلْعِلْمِ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"And when their messengers came to them with clear proofs, they [merely] rejoiced in what they had of knowledge, but they were enveloped by what they used to ridicule.","tr":"Falamma jaat-hum rusuluhum bilbayyinatifarihoo bima AAindahum mina alAAilmi wahaqabihim ma kanoo bihi yastahzi-oon","juz":24,"page":476},{"s":40,"a":84,"key":"40:84","ar":"فَلَمَّا رَأَوْا۟ بَأْسَنَا قَالُوٓا۟ ءَامَنَّا بِٱللَّهِ وَحْدَهُۥ وَكَفَرْنَا بِمَا كُنَّا بِهِۦ مُشْرِكِينَ","en":"And when they saw Our punishment, they said, \"We believe in Allāh alone and disbelieve in that which we used to associate with Him.\"","tr":"Falamma raaw ba/sana qalooamanna billahi wahdahuwakafarna bima kunna bihi mushrikeen","juz":24,"page":476},{"s":40,"a":85,"key":"40:85","ar":"فَلَمْ يَكُ يَنفَعُهُمْ إِيمَـٰنُهُمْ لَمَّا رَأَوْا۟ بَأْسَنَا ۖ سُنَّتَ ٱللَّهِ ٱلَّتِى قَدْ خَلَتْ فِى عِبَادِهِۦ ۖ وَخَسِرَ هُنَالِكَ ٱلْكَـٰفِرُونَ","en":"But never did their faith benefit them once they saw Our punishment. [It is] the established way of Allāh which has preceded among His servants. And the disbelievers thereupon lost [all].","tr":"Falam yaku yanfaAAuhum eemanuhum lammaraaw ba/sana sunnata Allahi allatee qad khalat feeAAibadihi wakhasira hunalika alkafiroon","juz":24,"page":476},{"s":41,"a":1,"key":"41:1","ar":" حمٓ","en":"Ḥā, Meem.1","tr":"Ha-meem","juz":24,"page":477},{"s":41,"a":2,"key":"41:2","ar":"تَنزِيلٌ مِّنَ ٱلرَّحْمَـٰنِ ٱلرَّحِيمِ","en":"[This is] a revelation from the Entirely Merciful, the Especially Merciful -","tr":"Tanzeelun mina arrahmaniarraheem","juz":24,"page":477},{"s":41,"a":3,"key":"41:3","ar":"كِتَـٰبٌ فُصِّلَتْ ءَايَـٰتُهُۥ قُرْءَانًا عَرَبِيًّا لِّقَوْمٍ يَعْلَمُونَ","en":"A Book whose verses have been detailed, an Arabic Qur’ān1 for a people who know,","tr":"Kitabun fussilat ayatuhuqur-anan AAarabiyyan liqawmin yaAAlamoon","juz":24,"page":477},{"s":41,"a":4,"key":"41:4","ar":"بَشِيرًا وَنَذِيرًا فَأَعْرَضَ أَكْثَرُهُمْ فَهُمْ لَا يَسْمَعُونَ","en":"As a giver of good tidings and a warner; but most of them turn away, so they do not hear.","tr":"Basheeran wanatheeran faaAAradaaktharuhum fahum la yasmaAAoon","juz":24,"page":477},{"s":41,"a":5,"key":"41:5","ar":"وَقَالُوا۟ قُلُوبُنَا فِىٓ أَكِنَّةٍ مِّمَّا تَدْعُونَآ إِلَيْهِ وَفِىٓ ءَاذَانِنَا وَقْرٌ وَمِنۢ بَيْنِنَا وَبَيْنِكَ حِجَابٌ فَٱعْمَلْ إِنَّنَا عَـٰمِلُونَ","en":"And they say, \"Our hearts are within coverings [i.e., screened] from that to which you invite us, and in our ears is deafness, and between us and you is a partition, so work;1 indeed, we are working.\"","tr":"Waqaloo quloobuna fee akinnatinmimma tadAAoona ilayhi wafee athaninawaqrun wamin baynina wabaynika hijabun faAAmalinnana AAamiloon","juz":24,"page":477},{"s":41,"a":6,"key":"41:6","ar":"قُلْ إِنَّمَآ أَنَا۠ بَشَرٌ مِّثْلُكُمْ يُوحَىٰٓ إِلَىَّ أَنَّمَآ إِلَـٰهُكُمْ إِلَـٰهٌ وَٰحِدٌ فَٱسْتَقِيمُوٓا۟ إِلَيْهِ وَٱسْتَغْفِرُوهُ ۗ وَوَيْلٌ لِّلْمُشْرِكِينَ","en":"Say, [O Muḥammad], \"I am only a man like you to whom it has been revealed that your god is but one God; so take a straight course to Him and seek His forgiveness.\" And woe to those who associate others with Allāh","tr":"Qul innama ana basharunmithlukum yooha ilayya annama ilahukum ilahunwahidun fastaqeemoo ilayhi wastaghfiroohuwawaylun lilmushrikeen","juz":24,"page":477},{"s":41,"a":7,"key":"41:7","ar":"ٱلَّذِينَ لَا يُؤْتُونَ ٱلزَّكَوٰةَ وَهُم بِٱلْـَٔاخِرَةِ هُمْ كَـٰفِرُونَ","en":"Those who do not give zakāh, and in the Hereafter they are disbelievers.","tr":"Allatheena la yu/toona azzakatawahum bil-akhirati hum kafiroon","juz":24,"page":477},{"s":41,"a":8,"key":"41:8","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَهُمْ أَجْرٌ غَيْرُ مَمْنُونٍ","en":"Indeed, those who believe and do righteous deeds - for them is a reward uninterrupted.","tr":"Inna allatheena amanoowaAAamiloo assalihati lahum ajrun ghayrumamnoon","juz":24,"page":477},{"s":41,"a":9,"key":"41:9","ar":"۞ قُلْ أَئِنَّكُمْ لَتَكْفُرُونَ بِٱلَّذِى خَلَقَ ٱلْأَرْضَ فِى يَوْمَيْنِ وَتَجْعَلُونَ لَهُۥٓ أَندَادًا ۚ ذَٰلِكَ رَبُّ ٱلْعَـٰلَمِينَ","en":"Say, \"Do you indeed disbelieve in He who created the earth in two days and attribute to Him equals? That is the Lord of the worlds.\"","tr":"Qul a-innakum latakfuroona billatheekhalaqa al-arda fee yawmayni watajAAaloona lahu andadanthalika rabbu alAAalameen","juz":24,"page":477},{"s":41,"a":10,"key":"41:10","ar":"وَجَعَلَ فِيهَا رَوَٰسِىَ مِن فَوْقِهَا وَبَـٰرَكَ فِيهَا وَقَدَّرَ فِيهَآ أَقْوَٰتَهَا فِىٓ أَرْبَعَةِ أَيَّامٍ سَوَآءً لِّلسَّآئِلِينَ","en":"And He placed on it [i.e., the earth] firmly set mountains over its surface, and He blessed it and determined therein its [creatures'] sustenance in four days without distinction1 - for [the information of] those who ask.","tr":"WajaAAala feeha rawasiya minfawqiha wabaraka feeha waqaddara feehaaqwataha fee arbaAAati ayyamin sawaanlissa-ileen","juz":24,"page":477},{"s":41,"a":11,"key":"41:11","ar":"ثُمَّ ٱسْتَوَىٰٓ إِلَى ٱلسَّمَآءِ وَهِىَ دُخَانٌ فَقَالَ لَهَا وَلِلْأَرْضِ ٱئْتِيَا طَوْعًا أَوْ كَرْهًا قَالَتَآ أَتَيْنَا طَآئِعِينَ","en":"Then He directed Himself1 to the heaven while it was smoke and said to it and to the earth, \"Come [into being],2 willingly or by compulsion.\" They said, \"We have come willingly.\"","tr":"Thumma istawa ila assama-iwahiya dukhanun faqala laha walil-ardii/tiya tawAAan aw karhan qalata ataynata-iAAeen","juz":24,"page":477},{"s":41,"a":12,"key":"41:12","ar":"فَقَضَىٰهُنَّ سَبْعَ سَمَـٰوَاتٍ فِى يَوْمَيْنِ وَأَوْحَىٰ فِى كُلِّ سَمَآءٍ أَمْرَهَا ۚ وَزَيَّنَّا ٱلسَّمَآءَ ٱلدُّنْيَا بِمَصَـٰبِيحَ وَحِفْظًا ۚ ذَٰلِكَ تَقْدِيرُ ٱلْعَزِيزِ ٱلْعَلِيمِ","en":"And He completed them as seven heavens within two days and inspired [i.e., made known] in each heaven its command. And We adorned the nearest heaven with lamps [i.e., stars, for beauty] and as protection.1 That is the determination of the Exalted in Might, the Knowing.","tr":"Faqadahunna sabAAa samawatinfee yawmayni waawha fee kulli sama-in amrahawazayyanna assamaa addunyabimasabeeha wahifthan thalikataqdeeru alAAazeezi alAAaleem","juz":24,"page":478},{"s":41,"a":13,"key":"41:13","ar":"فَإِنْ أَعْرَضُوا۟ فَقُلْ أَنذَرْتُكُمْ صَـٰعِقَةً مِّثْلَ صَـٰعِقَةِ عَادٍ وَثَمُودَ","en":"But if they turn away, then say, \"I have warned you of a thunderbolt like the thunderbolt [that struck] ʿAad and Thamūd.","tr":"Fa-in aAAradoo fuqul anthartukumsaAAiqatan mithla saAAiqati AAadin wathamood","juz":24,"page":478},{"s":41,"a":14,"key":"41:14","ar":"إِذْ جَآءَتْهُمُ ٱلرُّسُلُ مِنۢ بَيْنِ أَيْدِيهِمْ وَمِنْ خَلْفِهِمْ أَلَّا تَعْبُدُوٓا۟ إِلَّا ٱللَّهَ ۖ قَالُوا۟ لَوْ شَآءَ رَبُّنَا لَأَنزَلَ مَلَـٰٓئِكَةً فَإِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَـٰفِرُونَ","en":"[That occurred] when the messengers had come to them before them and after them, [saying], \"Worship not except Allāh.\" They said, \"If our Lord had willed,1 He would have sent down the angels, so indeed we, in that with which you have been sent, are disbelievers.\"","tr":"Ith jaat-humu arrusulumin bayni aydeehim wamin khalfihim alla taAAbudoo illaAllaha qaloo law shaa rabbunalaanzala mala-ikatan fa-inna bima orsiltumbihi kafiroon","juz":24,"page":478},{"s":41,"a":15,"key":"41:15","ar":"فَأَمَّا عَادٌ فَٱسْتَكْبَرُوا۟ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَقَالُوا۟ مَنْ أَشَدُّ مِنَّا قُوَّةً ۖ أَوَلَمْ يَرَوْا۟ أَنَّ ٱللَّهَ ٱلَّذِى خَلَقَهُمْ هُوَ أَشَدُّ مِنْهُمْ قُوَّةً ۖ وَكَانُوا۟ بِـَٔايَـٰتِنَا يَجْحَدُونَ","en":"As for ʿAad, they were arrogant upon the earth without right and said, \"Who is greater than us in strength?\" Did they not consider that Allāh who created them was greater than them in strength? But they were rejecting Our signs.","tr":"Faamma AAadun fastakbaroofee al-ardi bighayri alhaqqi waqaloo manashaddu minna quwwatan awa lam yaraw anna Allahaallathee khalaqahum huwa ashaddu minhum quwwatan wakanoobi-ayatina yajhadoon","juz":24,"page":478},{"s":41,"a":16,"key":"41:16","ar":"فَأَرْسَلْنَا عَلَيْهِمْ رِيحًا صَرْصَرًا فِىٓ أَيَّامٍ نَّحِسَاتٍ لِّنُذِيقَهُمْ عَذَابَ ٱلْخِزْىِ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَلَعَذَابُ ٱلْـَٔاخِرَةِ أَخْزَىٰ ۖ وَهُمْ لَا يُنصَرُونَ","en":"So We sent upon them a screaming wind during days of misfortune to make them taste the punishment of disgrace in the worldly life; but the punishment of the Hereafter is more disgracing, and they will not be helped.","tr":"Faarsalna AAalayhim reehan sarsaranfee ayyamin nahisatin linutheeqahumAAathaba alkhizyi fee alhayati addunyawalaAAathabu al-akhirati akhza wahum layunsaroon","juz":24,"page":478},{"s":41,"a":17,"key":"41:17","ar":"وَأَمَّا ثَمُودُ فَهَدَيْنَـٰهُمْ فَٱسْتَحَبُّوا۟ ٱلْعَمَىٰ عَلَى ٱلْهُدَىٰ فَأَخَذَتْهُمْ صَـٰعِقَةُ ٱلْعَذَابِ ٱلْهُونِ بِمَا كَانُوا۟ يَكْسِبُونَ","en":"And as for Thamūd, We guided them, but they preferred blindness over guidance, so the thunderbolt of humiliating punishment seized them for what they used to earn.","tr":"Waamma thamoodu fahadaynahumfastahabboo alAAama AAala alhudafaakhathat-hum saAAiqatu alAAathabi alhoonibima kanoo yaksiboon","juz":24,"page":478},{"s":41,"a":18,"key":"41:18","ar":"وَنَجَّيْنَا ٱلَّذِينَ ءَامَنُوا۟ وَكَانُوا۟ يَتَّقُونَ","en":"And We saved those who believed and used to fear Allāh.","tr":"Wanajjayna allatheena amanoowakanoo yattaqoon","juz":24,"page":478},{"s":41,"a":19,"key":"41:19","ar":"وَيَوْمَ يُحْشَرُ أَعْدَآءُ ٱللَّهِ إِلَى ٱلنَّارِ فَهُمْ يُوزَعُونَ","en":"And [mention, O Muḥammad], the Day when the enemies of Allāh will be gathered to the Fire while they are [driven], assembled in rows,","tr":"Wayawma yuhsharu aAAdao Allahiila annari fahum yoozaAAoon","juz":24,"page":478},{"s":41,"a":20,"key":"41:20","ar":"حَتَّىٰٓ إِذَا مَا جَآءُوهَا شَهِدَ عَلَيْهِمْ سَمْعُهُمْ وَأَبْصَـٰرُهُمْ وَجُلُودُهُم بِمَا كَانُوا۟ يَعْمَلُونَ","en":"Until, when they reach it, their hearing and their eyes and their skins will testify against them of what they used to do.","tr":"Hatta itha ma jaoohashahida AAalayhim samAAuhum waabsaruhum wajulooduhum bimakanoo yaAAmaloon","juz":24,"page":478},{"s":41,"a":21,"key":"41:21","ar":"وَقَالُوا۟ لِجُلُودِهِمْ لِمَ شَهِدتُّمْ عَلَيْنَا ۖ قَالُوٓا۟ أَنطَقَنَا ٱللَّهُ ٱلَّذِىٓ أَنطَقَ كُلَّ شَىْءٍ وَهُوَ خَلَقَكُمْ أَوَّلَ مَرَّةٍ وَإِلَيْهِ تُرْجَعُونَ","en":"And they will say to their skins, \"Why have you testified against us?\" They will say, \"We were made to speak by Allāh, who has made everything speak; and He created you the first time, and to Him you are returned.","tr":"Waqaloo lijuloodihim lima shahidtumAAalayna qaloo antaqana Allahuallathee antaqa kulla shay-in wahuwa khalaqakumawwala marratin wa-ilayhi turjaAAoon","juz":24,"page":479},{"s":41,"a":22,"key":"41:22","ar":"وَمَا كُنتُمْ تَسْتَتِرُونَ أَن يَشْهَدَ عَلَيْكُمْ سَمْعُكُمْ وَلَآ أَبْصَـٰرُكُمْ وَلَا جُلُودُكُمْ وَلَـٰكِن ظَنَنتُمْ أَنَّ ٱللَّهَ لَا يَعْلَمُ كَثِيرًا مِّمَّا تَعْمَلُونَ","en":"And you were not covering [i.e., protecting] yourselves,1 lest your hearing testify against you or your sight or your skins, but you assumed that Allāh does not know much of what you do.","tr":"Wama kuntum tastatiroona an yashhadaAAalaykum samAAukum wala absarukum walajuloodukum walakin thanantum anna Allahala yaAAlamu katheeran mimma taAAmaloon","juz":24,"page":479},{"s":41,"a":23,"key":"41:23","ar":"وَذَٰلِكُمْ ظَنُّكُمُ ٱلَّذِى ظَنَنتُم بِرَبِّكُمْ أَرْدَىٰكُمْ فَأَصْبَحْتُم مِّنَ ٱلْخَـٰسِرِينَ","en":"And that was your assumption which you assumed about your Lord. It has brought you to ruin, and you have become among the losers.\"","tr":"Wathalikum thannukumuallathee thanantum birabbikum ardakumfaasbahtum mina alkhasireen","juz":24,"page":479},{"s":41,"a":24,"key":"41:24","ar":"فَإِن يَصْبِرُوا۟ فَٱلنَّارُ مَثْوًى لَّهُمْ ۖ وَإِن يَسْتَعْتِبُوا۟ فَمَا هُم مِّنَ ٱلْمُعْتَبِينَ","en":"So [even] if they are patient, the Fire is a residence for them; and if they ask to appease [Allāh], they will not be of those who are allowed to appease.","tr":"Fa-in yasbiroo fannarumathwan lahum wa-in yastaAAtiboo fama hum minaalmuAAtabeen","juz":24,"page":479},{"s":41,"a":25,"key":"41:25","ar":"۞ وَقَيَّضْنَا لَهُمْ قُرَنَآءَ فَزَيَّنُوا۟ لَهُم مَّا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُمْ وَحَقَّ عَلَيْهِمُ ٱلْقَوْلُ فِىٓ أُمَمٍ قَدْ خَلَتْ مِن قَبْلِهِم مِّنَ ٱلْجِنِّ وَٱلْإِنسِ ۖ إِنَّهُمْ كَانُوا۟ خَـٰسِرِينَ","en":"And We appointed for them companions1 who made attractive to them what was before them and what was behind them [of sin], and the word [i.e., decree] has come into effect upon them among nations which had passed on before them of jinn and men. Indeed, they [all] were losers.","tr":"Waqayyadna lahum quranaafazayyanoo lahum ma bayna aydeehim wama khalfahumwahaqqa AAalayhimu alqawlu fee omamin qad khalat minqablihim mina aljinni wal-insi innahum kanoo khasireen","juz":24,"page":479},{"s":41,"a":26,"key":"41:26","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَا تَسْمَعُوا۟ لِهَـٰذَا ٱلْقُرْءَانِ وَٱلْغَوْا۟ فِيهِ لَعَلَّكُمْ تَغْلِبُونَ","en":"And those who disbelieve say, \"Do not listen to this Qur’ān and speak noisily1 during [the recitation of] it that perhaps you will overcome.\"","tr":"Waqala allatheena kafaroo latasmaAAoo lihatha alqur-ani walghaw feehilaAAallakum taghliboon","juz":24,"page":479},{"s":41,"a":27,"key":"41:27","ar":"فَلَنُذِيقَنَّ ٱلَّذِينَ كَفَرُوا۟ عَذَابًا شَدِيدًا وَلَنَجْزِيَنَّهُمْ أَسْوَأَ ٱلَّذِى كَانُوا۟ يَعْمَلُونَ","en":"But We will surely cause those who disbelieve to taste a severe punishment, and We will surely recompense them for the worst of what they had been doing.","tr":"Falanutheeqanna allatheenakafaroo AAathaban shadeedan walanajziyannahum aswaa allatheekanoo yaAAmaloon","juz":24,"page":479},{"s":41,"a":28,"key":"41:28","ar":"ذَٰلِكَ جَزَآءُ أَعْدَآءِ ٱللَّهِ ٱلنَّارُ ۖ لَهُمْ فِيهَا دَارُ ٱلْخُلْدِ ۖ جَزَآءًۢ بِمَا كَانُوا۟ بِـَٔايَـٰتِنَا يَجْحَدُونَ","en":"That is the recompense of the enemies of Allāh - the Fire. For them therein is the home of eternity as recompense for what they, of Our verses, were rejecting.","tr":"Thalika jazao aAAda-iAllahi annaru lahum feeha darualkhuldi jazaan bima kanoo bi-ayatinayajhadoon","juz":24,"page":479},{"s":41,"a":29,"key":"41:29","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوا۟ رَبَّنَآ أَرِنَا ٱلَّذَيْنِ أَضَلَّانَا مِنَ ٱلْجِنِّ وَٱلْإِنسِ نَجْعَلْهُمَا تَحْتَ أَقْدَامِنَا لِيَكُونَا مِنَ ٱلْأَسْفَلِينَ","en":"And those who disbelieved will [then] say, \"Our Lord, show us those who misled us of the jinn and men [so] we may put them under our feet1 that they will be among the lowest.\"","tr":"Waqala allatheena kafaroorabbana arina allathayni adallanamina aljinni wal-insi najAAalhuma tahta aqdaminaliyakoona mina al-asfaleen","juz":24,"page":479},{"s":41,"a":30,"key":"41:30","ar":"إِنَّ ٱلَّذِينَ قَالُوا۟ رَبُّنَا ٱللَّهُ ثُمَّ ٱسْتَقَـٰمُوا۟ تَتَنَزَّلُ عَلَيْهِمُ ٱلْمَلَـٰٓئِكَةُ أَلَّا تَخَافُوا۟ وَلَا تَحْزَنُوا۟ وَأَبْشِرُوا۟ بِٱلْجَنَّةِ ٱلَّتِى كُنتُمْ تُوعَدُونَ","en":"Indeed, those who have said, \"Our Lord is Allāh\" and then remained on a right course - the angels will descend upon them, [saying], \"Do not fear and do not grieve but receive good tidings of Paradise, which you were promised.","tr":"Inna allatheena qaloo rabbunaAllahu thumma istaqamoo tatanazzalu AAalayhimualmala-ikatu alla takhafoo wala tahzanoowaabshiroo biljannati allatee kuntum tooAAadoon","juz":24,"page":480},{"s":41,"a":31,"key":"41:31","ar":"نَحْنُ أَوْلِيَآؤُكُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا وَفِى ٱلْـَٔاخِرَةِ ۖ وَلَكُمْ فِيهَا مَا تَشْتَهِىٓ أَنفُسُكُمْ وَلَكُمْ فِيهَا مَا تَدَّعُونَ","en":"We [angels] were your allies in worldly life and [are so] in the Hereafter. And you will have therein whatever your souls desire, and you will have therein whatever you request [or wish]","tr":"Nahnu awliyaokum fee alhayatiaddunya wafee al-akhirati walakum feehama tashtahee anfusukum walakum feeha mataddaAAoon","juz":24,"page":480},{"s":41,"a":32,"key":"41:32","ar":"نُزُلًا مِّنْ غَفُورٍ رَّحِيمٍ","en":"As accommodation from a [Lord who is] Forgiving and Merciful.\"","tr":"Nuzulan min ghafoorin raheem","juz":24,"page":480},{"s":41,"a":33,"key":"41:33","ar":"وَمَنْ أَحْسَنُ قَوْلًا مِّمَّن دَعَآ إِلَى ٱللَّهِ وَعَمِلَ صَـٰلِحًا وَقَالَ إِنَّنِى مِنَ ٱلْمُسْلِمِينَ","en":"And who is better in speech than one who invites to Allāh and does righteousness and says, \"Indeed, I am of the Muslims.\"","tr":"Waman ahsanu qawlan mimman daAAaila Allahi waAAamila salihan waqalainnanee mina almuslimeen","juz":24,"page":480},{"s":41,"a":34,"key":"41:34","ar":"وَلَا تَسْتَوِى ٱلْحَسَنَةُ وَلَا ٱلسَّيِّئَةُ ۚ ٱدْفَعْ بِٱلَّتِى هِىَ أَحْسَنُ فَإِذَا ٱلَّذِى بَيْنَكَ وَبَيْنَهُۥ عَدَٰوَةٌ كَأَنَّهُۥ وَلِىٌّ حَمِيمٌ","en":"And not equal are the good deed and the bad. Repel [evil] by that [deed] which is better; and thereupon, the one whom between you and him is enmity [will become] as though he was a devoted friend.","tr":"Wala tastawee alhasanatu walaassayyi-atu idfaAA billatee hiya ahsanufa-itha allathee baynaka wabaynahu AAadawatunkaannahu waliyyun hameem","juz":24,"page":480},{"s":41,"a":35,"key":"41:35","ar":"وَمَا يُلَقَّىٰهَآ إِلَّا ٱلَّذِينَ صَبَرُوا۟ وَمَا يُلَقَّىٰهَآ إِلَّا ذُو حَظٍّ عَظِيمٍ","en":"But none is granted it except those who are patient, and none is granted it except one having a great portion [of good].","tr":"Wama yulaqqaha illaallatheena sabaroo wama yulaqqahailla thoo haththin AAatheem","juz":24,"page":480},{"s":41,"a":36,"key":"41:36","ar":"وَإِمَّا يَنزَغَنَّكَ مِنَ ٱلشَّيْطَـٰنِ نَزْغٌ فَٱسْتَعِذْ بِٱللَّهِ ۖ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"And if there comes to you from Satan an evil suggestion, then seek refuge in Allāh. Indeed, He is the Hearing, the Knowing.","tr":"Wa-imma yanzaghannaka mina ashshaytaninazghun fastaAAith billahi innahuhuwa assameeAAu alAAaleem","juz":24,"page":480},{"s":41,"a":37,"key":"41:37","ar":"وَمِنْ ءَايَـٰتِهِ ٱلَّيْلُ وَٱلنَّهَارُ وَٱلشَّمْسُ وَٱلْقَمَرُ ۚ لَا تَسْجُدُوا۟ لِلشَّمْسِ وَلَا لِلْقَمَرِ وَٱسْجُدُوا۟ لِلَّهِ ٱلَّذِى خَلَقَهُنَّ إِن كُنتُمْ إِيَّاهُ تَعْبُدُونَ","en":"And of His signs are the night and day and the sun and moon. Do not prostrate to the sun or to the moon, but prostrate to Allāh, who created them, if it should be Him that you worship.1","tr":"Wamin ayatihi allaylu wannaharuwashshamsu walqamaru la tasjudoo lishshamsiwala lilqamari wasjudoo lillahi alatheekhalaqahunna in kuntum iyyahu taAAbudoon","juz":24,"page":480},{"s":41,"a":38,"key":"41:38","ar":"فَإِنِ ٱسْتَكْبَرُوا۟ فَٱلَّذِينَ عِندَ رَبِّكَ يُسَبِّحُونَ لَهُۥ بِٱلَّيْلِ وَٱلنَّهَارِ وَهُمْ لَا يَسْـَٔمُونَ ۩","en":"But if they are arrogant - then those who are near your Lord [i.e., the angels] exalt Him by night and by day, and they do not become weary.","tr":"Fa-ini istakbaroo fallatheenaAAinda rabbika yusabbihoona lahu billayli wannahariwahum la yas-amoon","juz":24,"page":480},{"s":41,"a":39,"key":"41:39","ar":"وَمِنْ ءَايَـٰتِهِۦٓ أَنَّكَ تَرَى ٱلْأَرْضَ خَـٰشِعَةً فَإِذَآ أَنزَلْنَا عَلَيْهَا ٱلْمَآءَ ٱهْتَزَّتْ وَرَبَتْ ۚ إِنَّ ٱلَّذِىٓ أَحْيَاهَا لَمُحْىِ ٱلْمَوْتَىٰٓ ۚ إِنَّهُۥ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"And of His signs is that you see the earth stilled, but when We send down upon it rain, it quivers and grows. Indeed, He who has given it life is the Giver of Life to the dead. Indeed, He is over all things competent.","tr":"Wamin ayatihi annaka taraal-arda khashiAAatan fa-itha anzalnaAAalayha almaa ihtazzat warabat inna allatheeahyaha lamuhyee almawta innahuAAala kulli shay-in qadeer","juz":24,"page":481},{"s":41,"a":40,"key":"41:40","ar":"إِنَّ ٱلَّذِينَ يُلْحِدُونَ فِىٓ ءَايَـٰتِنَا لَا يَخْفَوْنَ عَلَيْنَآ ۗ أَفَمَن يُلْقَىٰ فِى ٱلنَّارِ خَيْرٌ أَم مَّن يَأْتِىٓ ءَامِنًا يَوْمَ ٱلْقِيَـٰمَةِ ۚ ٱعْمَلُوا۟ مَا شِئْتُمْ ۖ إِنَّهُۥ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"Indeed, those who inject deviation into Our verses1 are not concealed from Us. So, is he who is cast into the Fire better or he who comes secure on the Day of Resurrection? Do whatever you will; indeed, He is Seeing of what you do.","tr":"Inna allatheena yulhidoona feeayatina la yakhfawna AAalaynaafaman yulqa fee annari khayrun ammanya/tee aminan yawma alqiyamati iAAmaloo mashi/tum innahu bima taAAmaloona baseer","juz":24,"page":481},{"s":41,"a":41,"key":"41:41","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ بِٱلذِّكْرِ لَمَّا جَآءَهُمْ ۖ وَإِنَّهُۥ لَكِتَـٰبٌ عَزِيزٌ","en":"Indeed, those who disbelieve in the message [i.e., the Qur’ān]1 after it has come to them...2 And indeed, it is a mighty3 Book.","tr":"Inna allatheena kafaroo biththikrilamma jaahum wa-innahu lakitabun AAazeez","juz":24,"page":481},{"s":41,"a":42,"key":"41:42","ar":"لَّا يَأْتِيهِ ٱلْبَـٰطِلُ مِنۢ بَيْنِ يَدَيْهِ وَلَا مِنْ خَلْفِهِۦ ۖ تَنزِيلٌ مِّنْ حَكِيمٍ حَمِيدٍ","en":"Falsehood cannot approach it from before it or from behind it; [it is] a revelation from a [Lord who is] Wise and Praiseworthy.","tr":"La ya/teehi albatilu min bayniyadayhi wala min khalfihi tanzeelun min hakeemin hameed","juz":24,"page":481},{"s":41,"a":43,"key":"41:43","ar":"مَّا يُقَالُ لَكَ إِلَّا مَا قَدْ قِيلَ لِلرُّسُلِ مِن قَبْلِكَ ۚ إِنَّ رَبَّكَ لَذُو مَغْفِرَةٍ وَذُو عِقَابٍ أَلِيمٍ","en":"Nothing is said to you, [O Muḥammad], except what was already said to the messengers before you. Indeed, your Lord is a possessor of forgiveness and a possessor of painful penalty.","tr":"Ma yuqalu laka illa maqad qeela lirrusuli min qablika inna rabbaka lathoomaghfiratin wathoo AAiqabin aleem","juz":24,"page":481},{"s":41,"a":44,"key":"41:44","ar":"وَلَوْ جَعَلْنَـٰهُ قُرْءَانًا أَعْجَمِيًّا لَّقَالُوا۟ لَوْلَا فُصِّلَتْ ءَايَـٰتُهُۥٓ ۖ ءَا۬عْجَمِىٌّ وَعَرَبِىٌّ ۗ قُلْ هُوَ لِلَّذِينَ ءَامَنُوا۟ هُدًى وَشِفَآءٌ ۖ وَٱلَّذِينَ لَا يُؤْمِنُونَ فِىٓ ءَاذَانِهِمْ وَقْرٌ وَهُوَ عَلَيْهِمْ عَمًى ۚ أُو۟لَـٰٓئِكَ يُنَادَوْنَ مِن مَّكَانٍۭ بَعِيدٍ","en":"And if We had made it a foreign [i.e., non-Arabic] Qur’ān, they would have said, \"Why are its verses not explained in detail [in our language]? Is it a foreign [recitation] and an Arab [messenger]?\" Say, \"It is, for those who believe, a guidance and cure.\" And those who do not believe - in their ears is deafness, and it is upon them blindness. Those are being called from a distant place.1","tr":"Walaw jaAAalnahu qur-ananaAAjamiyyan laqaloo lawla fussilat ayatuhuaaAAjamiyyun waAAarabiyyun qul huwa lillatheena amanoohudan washifaon wallatheena layu/minoona fee athanihim waqrun wahuwa AAalayhim AAaman ola-ikayunadawna min makanin baAAeed","juz":24,"page":481},{"s":41,"a":45,"key":"41:45","ar":"وَلَقَدْ ءَاتَيْنَا مُوسَى ٱلْكِتَـٰبَ فَٱخْتُلِفَ فِيهِ ۗ وَلَوْلَا كَلِمَةٌ سَبَقَتْ مِن رَّبِّكَ لَقُضِىَ بَيْنَهُمْ ۚ وَإِنَّهُمْ لَفِى شَكٍّ مِّنْهُ مُرِيبٍ","en":"And We had already given Moses the Scripture, but it came under disagreement.1 And if not for a word [i.e., decree]2 that preceded from your Lord, it would have been concluded between them. And indeed they are, concerning it [i.e., the Qur’ān], in disquieting doubt.","tr":"Walaqad atayna moosaalkitaba fakhtulifa feehi walawla kalimatunsabaqat min rabbika laqudiya baynahum wa-innahum lafeeshakkin minhu mureeb","juz":24,"page":481},{"s":41,"a":46,"key":"41:46","ar":"مَّنْ عَمِلَ صَـٰلِحًا فَلِنَفْسِهِۦ ۖ وَمَنْ أَسَآءَ فَعَلَيْهَا ۗ وَمَا رَبُّكَ بِظَلَّـٰمٍ لِّلْعَبِيدِ","en":"Whoever does righteousness - it is for his [own] soul; and whoever does evil [does so] against it. And your Lord is not ever unjust to [His] servants.","tr":"Man AAamila salihanfalinafsihi waman asaa faAAalayha wamarabbuka bithallamin lilAAabeed","juz":24,"page":481},{"s":41,"a":47,"key":"41:47","ar":"۞ إِلَيْهِ يُرَدُّ عِلْمُ ٱلسَّاعَةِ ۚ وَمَا تَخْرُجُ مِن ثَمَرَٰتٍ مِّنْ أَكْمَامِهَا وَمَا تَحْمِلُ مِنْ أُنثَىٰ وَلَا تَضَعُ إِلَّا بِعِلْمِهِۦ ۚ وَيَوْمَ يُنَادِيهِمْ أَيْنَ شُرَكَآءِى قَالُوٓا۟ ءَاذَنَّـٰكَ مَا مِنَّا مِن شَهِيدٍ","en":"To Him [alone] is attributed knowledge of the Hour. And fruits emerge not from their coverings nor does a female conceive or give birth except with His knowledge. And the Day He will call to them, \"Where are My 'partners'?\" they will say, \"We announce to You that there is [no longer] among us any witness [to that].\"","tr":"Ilayhi yuraddu AAilmu assaAAatiwama takhruju min thamaratin min akmamihawama tahmilu min ontha wala tadaAAuilla biAAilmihi wayawma yunadeehim ayna shuraka-eeqaloo athannaka ma minna minshaheed","juz":25,"page":482},{"s":41,"a":48,"key":"41:48","ar":"وَضَلَّ عَنْهُم مَّا كَانُوا۟ يَدْعُونَ مِن قَبْلُ ۖ وَظَنُّوا۟ مَا لَهُم مِّن مَّحِيصٍ","en":"And lost from them will be those they were invoking before, and they will be certain that they have no place of escape.","tr":"Wadalla AAanhum ma kanooyadAAoona min qablu wathannoo ma lahum minmahees","juz":25,"page":482},{"s":41,"a":49,"key":"41:49","ar":"لَّا يَسْـَٔمُ ٱلْإِنسَـٰنُ مِن دُعَآءِ ٱلْخَيْرِ وَإِن مَّسَّهُ ٱلشَّرُّ فَيَـُٔوسٌ قَنُوطٌ","en":"Man is not weary of supplication for good [things], but if evil touches him, he is hopeless and despairing.","tr":"La yas-amu al-insanu min duAAa-ialkhayri wa-in massahu ashsharru fayaoosun qanoot","juz":25,"page":482},{"s":41,"a":50,"key":"41:50","ar":"وَلَئِنْ أَذَقْنَـٰهُ رَحْمَةً مِّنَّا مِنۢ بَعْدِ ضَرَّآءَ مَسَّتْهُ لَيَقُولَنَّ هَـٰذَا لِى وَمَآ أَظُنُّ ٱلسَّاعَةَ قَآئِمَةً وَلَئِن رُّجِعْتُ إِلَىٰ رَبِّىٓ إِنَّ لِى عِندَهُۥ لَلْحُسْنَىٰ ۚ فَلَنُنَبِّئَنَّ ٱلَّذِينَ كَفَرُوا۟ بِمَا عَمِلُوا۟ وَلَنُذِيقَنَّهُم مِّنْ عَذَابٍ غَلِيظٍ","en":"And if We let him taste mercy from Us after an adversity which has touched him, he will surely say, \"This is [due] to me,1 and I do not think the Hour will occur; and [even] if I should be returned to my Lord, indeed, for me there will be with Him the best.\" But We will surely inform those who disbelieved about what they did, and We will surely make them taste a massive punishment.","tr":"Wala-in athaqnahu rahmatanminna min baAAdi darraa massat-hulayaqoolanna hatha lee wama athunnu assaAAataqa-imatan wala-in rujiAAtu ila rabbee inna leeAAindahu lalhusna falanunabbi-anna allatheenakafaroo bima AAamiloo walanutheeqannahum min AAathabinghaleeth","juz":25,"page":482},{"s":41,"a":51,"key":"41:51","ar":"وَإِذَآ أَنْعَمْنَا عَلَى ٱلْإِنسَـٰنِ أَعْرَضَ وَنَـَٔا بِجَانِبِهِۦ وَإِذَا مَسَّهُ ٱلشَّرُّ فَذُو دُعَآءٍ عَرِيضٍ","en":"And when We bestow favor upon man, he turns away and distances himself; but when evil touches him, then he is full of extensive supplication.","tr":"Wa-itha anAAamna AAalaal-insani aAArada wanaa bijanibihiwa-itha massahu ashsharru fathoo duAAa-inAAareed","juz":25,"page":482},{"s":41,"a":52,"key":"41:52","ar":"قُلْ أَرَءَيْتُمْ إِن كَانَ مِنْ عِندِ ٱللَّهِ ثُمَّ كَفَرْتُم بِهِۦ مَنْ أَضَلُّ مِمَّنْ هُوَ فِى شِقَاقٍۭ بَعِيدٍ","en":"Say, \"Have you considered: if it [i.e., the Qur’ān] is from Allāh and you disbelieved in it, who would be more astray than one who is in extreme dissension?\"","tr":"Qul araaytum in kana min AAindi Allahithumma kafartum bihi man adallu mimman huwa fee shiqaqinbaAAeed","juz":25,"page":482},{"s":41,"a":53,"key":"41:53","ar":"سَنُرِيهِمْ ءَايَـٰتِنَا فِى ٱلْـَٔافَاقِ وَفِىٓ أَنفُسِهِمْ حَتَّىٰ يَتَبَيَّنَ لَهُمْ أَنَّهُ ٱلْحَقُّ ۗ أَوَلَمْ يَكْفِ بِرَبِّكَ أَنَّهُۥ عَلَىٰ كُلِّ شَىْءٍ شَهِيدٌ","en":"We will show them Our signs in the horizons and within themselves until it becomes clear to them that it is the truth.1 But is it not sufficient concerning your Lord that He is, over all things, a Witness?2","tr":"Sanureehim ayatina feeal-afaqi wafee anfusihim hattayatabayyana lahum annahu alhaqqu awa lam yakfi birabbikaannahu AAala kulli shay-in shaheed","juz":25,"page":482},{"s":41,"a":54,"key":"41:54","ar":"أَلَآ إِنَّهُمْ فِى مِرْيَةٍ مِّن لِّقَآءِ رَبِّهِمْ ۗ أَلَآ إِنَّهُۥ بِكُلِّ شَىْءٍ مُّحِيطٌۢ","en":"Unquestionably, they are in doubt about the meeting with their Lord. Unquestionably He is, of all things, encompassing.","tr":"Ala innahum fee miryatin min liqa-irabbihim ala innahu bikulli shay-in muheet","juz":25,"page":482},{"s":42,"a":1,"key":"42:1","ar":" حمٓ","en":"Ḥā, Meem.","tr":"Ha-meem","juz":25,"page":483},{"s":42,"a":2,"key":"42:2","ar":"عٓسٓقٓ","en":"ʿAyn, Seen, Qāf.1","tr":"AAayn-seen-qaf","juz":25,"page":483},{"s":42,"a":3,"key":"42:3","ar":"كَذَٰلِكَ يُوحِىٓ إِلَيْكَ وَإِلَى ٱلَّذِينَ مِن قَبْلِكَ ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Thus has He revealed to you, [O Muḥammad], and to those before you - Allāh, the Exalted in Might, the Wise.","tr":"Kathalika yoohee ilayka wa-ilaallatheena min qablika Allahu alAAazeezu alhakeem","juz":25,"page":483},{"s":42,"a":4,"key":"42:4","ar":"لَهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ وَهُوَ ٱلْعَلِىُّ ٱلْعَظِيمُ","en":"To Him belongs whatever is in the heavens and whatever is in the earth, and He is the Most High, the Most Great.1","tr":"Lahu ma fee assamawatiwama fee al-ardi wahuwa alAAaliyyu alAAatheem","juz":25,"page":483},{"s":42,"a":5,"key":"42:5","ar":"تَكَادُ ٱلسَّمَـٰوَٰتُ يَتَفَطَّرْنَ مِن فَوْقِهِنَّ ۚ وَٱلْمَلَـٰٓئِكَةُ يُسَبِّحُونَ بِحَمْدِ رَبِّهِمْ وَيَسْتَغْفِرُونَ لِمَن فِى ٱلْأَرْضِ ۗ أَلَآ إِنَّ ٱللَّهَ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ","en":"The heavens almost break from above them,1 and the angels exalt [Allāh] with praise of their Lord and ask forgiveness for those on earth. Unquestionably, it is Allāh who is the Forgiving, the Merciful.","tr":"Takadu assamawatuyatafattarna min fawqihinna walmala-ikatuyusabbihoona bihamdi rabbihim wayastaghfiroonaliman fee al-ardi ala inna Allaha huwaalghafooru arraheem","juz":25,"page":483},{"s":42,"a":6,"key":"42:6","ar":"وَٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ ٱللَّهُ حَفِيظٌ عَلَيْهِمْ وَمَآ أَنتَ عَلَيْهِم بِوَكِيلٍ","en":"And those who take as allies other than Him - Allāh is [yet] Guardian over them; and you, [O Muḥammad], are not over them a manager.","tr":"Wallatheena ittakhathoomin doonihi awliyaa Allahu hafeethunAAalayhim wama anta AAalayhim biwakeel","juz":25,"page":483},{"s":42,"a":7,"key":"42:7","ar":"وَكَذَٰلِكَ أَوْحَيْنَآ إِلَيْكَ قُرْءَانًا عَرَبِيًّا لِّتُنذِرَ أُمَّ ٱلْقُرَىٰ وَمَنْ حَوْلَهَا وَتُنذِرَ يَوْمَ ٱلْجَمْعِ لَا رَيْبَ فِيهِ ۚ فَرِيقٌ فِى ٱلْجَنَّةِ وَفَرِيقٌ فِى ٱلسَّعِيرِ","en":"And thus We have revealed to you an Arabic Qur’ān that you may warn the Mother of Cities [i.e., Makkah] and those around it1 and warn of the Day of Assembly, about which there is no doubt. A party will be in Paradise and a party in the Blaze.","tr":"Wakathalika awhaynailayka qur-anan AAarabiyyan litunthira omma alqurawaman hawlaha watunthira yawma aljamAAi larayba feehi fareequn fee aljannati wafareequn fee assaAAeer","juz":25,"page":483},{"s":42,"a":8,"key":"42:8","ar":"وَلَوْ شَآءَ ٱللَّهُ لَجَعَلَهُمْ أُمَّةً وَٰحِدَةً وَلَـٰكِن يُدْخِلُ مَن يَشَآءُ فِى رَحْمَتِهِۦ ۚ وَٱلظَّـٰلِمُونَ مَا لَهُم مِّن وَلِىٍّ وَلَا نَصِيرٍ","en":"And if Allāh willed, He could have made them [of] one religion, but He admits whom He wills1 into His mercy. And the wrongdoers have not any protector or helper.","tr":"Walaw shaa Allahu lajaAAalahumommatan wahidatan walakin yudkhilu man yashaofee rahmatihi waththalimoonama lahum min waliyyin wala naseer","juz":25,"page":483},{"s":42,"a":9,"key":"42:9","ar":"أَمِ ٱتَّخَذُوا۟ مِن دُونِهِۦٓ أَوْلِيَآءَ ۖ فَٱللَّهُ هُوَ ٱلْوَلِىُّ وَهُوَ يُحْىِ ٱلْمَوْتَىٰ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Or have they taken protectors [or allies] besides Him? But Allāh - He is the Protector, and He gives life to the dead, and He is over all things competent.","tr":"Ami ittakhathoo min doonihi awliyaafallahu huwa alwaliyyu wahuwa yuhyee almawtawahuwa AAala kulli shay-in qadeer","juz":25,"page":483},{"s":42,"a":10,"key":"42:10","ar":"وَمَا ٱخْتَلَفْتُمْ فِيهِ مِن شَىْءٍ فَحُكْمُهُۥٓ إِلَى ٱللَّهِ ۚ ذَٰلِكُمُ ٱللَّهُ رَبِّى عَلَيْهِ تَوَكَّلْتُ وَإِلَيْهِ أُنِيبُ","en":"And in anything over which you disagree - its ruling is [to be referred] to Allāh. [Say], \"That is Allāh, my Lord; upon Him I have relied, and to Him I turn back.\"1","tr":"Wama ikhtalaftum feehi min shay-in fahukmuhuila Allahi thalikumu Allahu rabbeeAAalayhi tawakkaltu wa-ilayhi oneeb","juz":25,"page":483},{"s":42,"a":11,"key":"42:11","ar":"فَاطِرُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ جَعَلَ لَكُم مِّنْ أَنفُسِكُمْ أَزْوَٰجًا وَمِنَ ٱلْأَنْعَـٰمِ أَزْوَٰجًا ۖ يَذْرَؤُكُمْ فِيهِ ۚ لَيْسَ كَمِثْلِهِۦ شَىْءٌ ۖ وَهُوَ ٱلسَّمِيعُ ٱلْبَصِيرُ","en":"[He is] Creator of the heavens and the earth. He has made for you from yourselves, mates, and among the cattle, mates; He multiplies you thereby. There is nothing like unto Him,1 and He is the Hearing, the Seeing.2","tr":"Fatiru assamawatiwal-ardi jaAAala lakum min anfusikum azwajanwamina al-anAAami azwajan yathraokum feehilaysa kamithlihi shay-on wahuwa assameeAAu albaseer","juz":25,"page":484},{"s":42,"a":12,"key":"42:12","ar":"لَهُۥ مَقَالِيدُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ ۚ إِنَّهُۥ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"To Him belong the keys of the heavens and the earth. He extends provision for whom He wills and restricts [it]. Indeed He is, of all things, Knowing.","tr":"Lahu maqaleedu assamawatiwal-ardi yabsutu arrizqa liman yashaowayaqdiru innahu bikulli shay-in AAaleem","juz":25,"page":484},{"s":42,"a":13,"key":"42:13","ar":"۞ شَرَعَ لَكُم مِّنَ ٱلدِّينِ مَا وَصَّىٰ بِهِۦ نُوحًا وَٱلَّذِىٓ أَوْحَيْنَآ إِلَيْكَ وَمَا وَصَّيْنَا بِهِۦٓ إِبْرَٰهِيمَ وَمُوسَىٰ وَعِيسَىٰٓ ۖ أَنْ أَقِيمُوا۟ ٱلدِّينَ وَلَا تَتَفَرَّقُوا۟ فِيهِ ۚ كَبُرَ عَلَى ٱلْمُشْرِكِينَ مَا تَدْعُوهُمْ إِلَيْهِ ۚ ٱللَّهُ يَجْتَبِىٓ إِلَيْهِ مَن يَشَآءُ وَيَهْدِىٓ إِلَيْهِ مَن يُنِيبُ","en":"He has ordained for you of religion what He enjoined upon Noah and that which We have revealed to you, [O Muḥammad], and what We enjoined upon Abraham and Moses and Jesus - to establish the religion and not be divided therein. Difficult for those who associate others with Allāh is that to which you invite them. Allāh chooses for Himself whom He wills and guides to Himself whoever turns back [to Him].","tr":"SharaAAa lakum mina addeeni mawassa bihi noohan wallathee awhaynailayka wama wassayna bihi ibraheemawamoosa waAAeesa an aqeemoo addeena walatatafarraqoo feehi kabura AAala almushrikeena matadAAoohum ilayhi Allahu yajtabee ilayhi man yashaowayahdee ilayhi man yuneeb","juz":25,"page":484},{"s":42,"a":14,"key":"42:14","ar":"وَمَا تَفَرَّقُوٓا۟ إِلَّا مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْعِلْمُ بَغْيًۢا بَيْنَهُمْ ۚ وَلَوْلَا كَلِمَةٌ سَبَقَتْ مِن رَّبِّكَ إِلَىٰٓ أَجَلٍ مُّسَمًّى لَّقُضِىَ بَيْنَهُمْ ۚ وَإِنَّ ٱلَّذِينَ أُورِثُوا۟ ٱلْكِتَـٰبَ مِنۢ بَعْدِهِمْ لَفِى شَكٍّ مِّنْهُ مُرِيبٍ","en":"And they did not become divided until after knowledge had come to them - out of jealous animosity between themselves. And if not for a word1 that preceded from your Lord [postponing the penalty] until a specified time, it would have been concluded between them. And indeed, those who were granted inheritance of the Scripture after them are, concerning it, in disquieting doubt.","tr":"Wama tafarraqoo illa minbaAAdi ma jaahumu alAAilmu baghyan baynahum walawlakalimatun sabaqat min rabbika ila ajalin musamman laqudiyabaynahum wa-inna allatheena oorithoo alkitaba minbaAAdihim lafee shakkin minhu mureeb","juz":25,"page":484},{"s":42,"a":15,"key":"42:15","ar":"فَلِذَٰلِكَ فَٱدْعُ ۖ وَٱسْتَقِمْ كَمَآ أُمِرْتَ ۖ وَلَا تَتَّبِعْ أَهْوَآءَهُمْ ۖ وَقُلْ ءَامَنتُ بِمَآ أَنزَلَ ٱللَّهُ مِن كِتَـٰبٍ ۖ وَأُمِرْتُ لِأَعْدِلَ بَيْنَكُمُ ۖ ٱللَّهُ رَبُّنَا وَرَبُّكُمْ ۖ لَنَآ أَعْمَـٰلُنَا وَلَكُمْ أَعْمَـٰلُكُمْ ۖ لَا حُجَّةَ بَيْنَنَا وَبَيْنَكُمُ ۖ ٱللَّهُ يَجْمَعُ بَيْنَنَا ۖ وَإِلَيْهِ ٱلْمَصِيرُ","en":"So to that [religion of Allāh] invite, [O Muḥammad],1 and remain on a right course as you are commanded and do not follow their inclinations but say, \"I have believed in what Allāh has revealed of scripture [i.e., the Qur’ān], and I have been commanded to do justice among you. Allāh is our Lord and your Lord. For us are our deeds, and for you your deeds.2 There is no [need for] argument between us and you.3 Allāh will bring us together, and to Him is the [final] destination.\"","tr":"Falithalika fadAAu wastaqimkama omirta wala tattabiAA ahwaahum waqul amantubima anzala Allahu min kitabin waomirtuli-aAAdila baynakum Allahu rabbuna warabbukum lanaaAAmaluna walakum aAAmalukum la hujjatabaynana wabaynakumu Allahu yajmaAAu baynanawa-ilayhi almaseer","juz":25,"page":484},{"s":42,"a":16,"key":"42:16","ar":"وَٱلَّذِينَ يُحَآجُّونَ فِى ٱللَّهِ مِنۢ بَعْدِ مَا ٱسْتُجِيبَ لَهُۥ حُجَّتُهُمْ دَاحِضَةٌ عِندَ رَبِّهِمْ وَعَلَيْهِمْ غَضَبٌ وَلَهُمْ عَذَابٌ شَدِيدٌ","en":"And those who argue concerning Allāh after He has been responded to1 - their argument is invalid with their Lord, and upon them is [His] wrath, and for them is a severe punishment.","tr":"Wallatheena yuhajjoonafee Allahi min baAAdi ma istujeeba lahu hujjatuhumdahidatun AAinda rabbihim waAAalayhim ghadabunwalahum AAathabun shadeed","juz":25,"page":485},{"s":42,"a":17,"key":"42:17","ar":"ٱللَّهُ ٱلَّذِىٓ أَنزَلَ ٱلْكِتَـٰبَ بِٱلْحَقِّ وَٱلْمِيزَانَ ۗ وَمَا يُدْرِيكَ لَعَلَّ ٱلسَّاعَةَ قَرِيبٌ","en":"It is Allāh who has sent down the Book in truth and [also] the balance [i.e., justice]. And what will make you perceive? Perhaps the Hour is near.","tr":"Allahu allathee anzala alkitababilhaqqi walmeezani wamayudreeka laAAalla assaAAata qareeb","juz":25,"page":485},{"s":42,"a":18,"key":"42:18","ar":"يَسْتَعْجِلُ بِهَا ٱلَّذِينَ لَا يُؤْمِنُونَ بِهَا ۖ وَٱلَّذِينَ ءَامَنُوا۟ مُشْفِقُونَ مِنْهَا وَيَعْلَمُونَ أَنَّهَا ٱلْحَقُّ ۗ أَلَآ إِنَّ ٱلَّذِينَ يُمَارُونَ فِى ٱلسَّاعَةِ لَفِى ضَلَـٰلٍۭ بَعِيدٍ","en":"Those who do not believe in it are impatient for it,1 but those who believe are fearful of it and know that it is the truth. Unquestionably, those who dispute concerning the Hour are in extreme error.","tr":"YastaAAjilu biha allatheena layu/minoona biha wallatheena amanoomushfiqoona minha wayaAAlamoona annaha alhaqquala inna allatheena yumaroona fee assaAAatilafee dalalin baAAeed","juz":25,"page":485},{"s":42,"a":19,"key":"42:19","ar":"ٱللَّهُ لَطِيفٌۢ بِعِبَادِهِۦ يَرْزُقُ مَن يَشَآءُ ۖ وَهُوَ ٱلْقَوِىُّ ٱلْعَزِيزُ","en":"Allāh is Subtle1 with His servants; He gives provision to whom He wills. And He is the Powerful, the Exalted in Might.","tr":"Allahu lateefun biAAibadihiyarzuqu man yashao wahuwa alqawiyyu alAAazeez","juz":25,"page":485},{"s":42,"a":20,"key":"42:20","ar":"مَن كَانَ يُرِيدُ حَرْثَ ٱلْـَٔاخِرَةِ نَزِدْ لَهُۥ فِى حَرْثِهِۦ ۖ وَمَن كَانَ يُرِيدُ حَرْثَ ٱلدُّنْيَا نُؤْتِهِۦ مِنْهَا وَمَا لَهُۥ فِى ٱلْـَٔاخِرَةِ مِن نَّصِيبٍ","en":"Whoever desires the harvest of the Hereafter - We increase for him in his harvest [i.e., reward]. And whoever desires the harvest [i.e., benefits] of this world - We give him thereof, but there is not for him in the Hereafter any share.","tr":"Man kana yureedu hartha al-akhiratinazid lahu fee harthihi waman kana yureedu harthaaddunya nu/tihi minha wama lahu feeal-akhirati min naseeb","juz":25,"page":485},{"s":42,"a":21,"key":"42:21","ar":"أَمْ لَهُمْ شُرَكَـٰٓؤُا۟ شَرَعُوا۟ لَهُم مِّنَ ٱلدِّينِ مَا لَمْ يَأْذَنۢ بِهِ ٱللَّهُ ۚ وَلَوْلَا كَلِمَةُ ٱلْفَصْلِ لَقُضِىَ بَيْنَهُمْ ۗ وَإِنَّ ٱلظَّـٰلِمِينَ لَهُمْ عَذَابٌ أَلِيمٌ","en":"Or have they partners [i.e., other deities] who have ordained for them a religion to which Allāh has not consented? But if not for the decisive word,1 it would have been concluded between them. And indeed, the wrongdoers will have a painful punishment.","tr":"Am lahum shurakao sharaAAoo lahummina addeeni ma lam ya/than bihi Allahuwalawla kalimatu alfasli laqudiya baynahumwa-inna aththalimeena lahum AAathabunaleem","juz":25,"page":485},{"s":42,"a":22,"key":"42:22","ar":"تَرَى ٱلظَّـٰلِمِينَ مُشْفِقِينَ مِمَّا كَسَبُوا۟ وَهُوَ وَاقِعٌۢ بِهِمْ ۗ وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ فِى رَوْضَاتِ ٱلْجَنَّاتِ ۖ لَهُم مَّا يَشَآءُونَ عِندَ رَبِّهِمْ ۚ ذَٰلِكَ هُوَ ٱلْفَضْلُ ٱلْكَبِيرُ","en":"You will see the wrongdoers fearful of what they have earned, and it will [certainly] befall them. And those who have believed and done righteous deeds will be in lush regions of the gardens [in Paradise] having whatever they will in the presence of their Lord. That is what is the great bounty.","tr":"Tara aththalimeenamushfiqeena mimma kasaboo wahuwa waqiAAun bihim wallatheenaamanoo waAAamiloo assalihati fee rawdatialjannati lahum ma yashaoona AAinda rabbihimthalika huwa alfadlu alkabeer","juz":25,"page":485},{"s":42,"a":23,"key":"42:23","ar":"ذَٰلِكَ ٱلَّذِى يُبَشِّرُ ٱللَّهُ عِبَادَهُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ ۗ قُل لَّآ أَسْـَٔلُكُمْ عَلَيْهِ أَجْرًا إِلَّا ٱلْمَوَدَّةَ فِى ٱلْقُرْبَىٰ ۗ وَمَن يَقْتَرِفْ حَسَنَةً نَّزِدْ لَهُۥ فِيهَا حُسْنًا ۚ إِنَّ ٱللَّهَ غَفُورٌ شَكُورٌ","en":"It is that of which Allāh gives good tidings to His servants who believe and do righteous deeds. Say, [O Muḥammad], \"I do not ask you for it [i.e., this message] any payment [but] only good will through [i.e., due to] kinship.\" And whoever commits a good deed - We will increase for him good therein. Indeed, Allāh is Forgiving and Appreciative.1","tr":"Thalika allathee yubashshiruAllahu AAibadahu allatheena amanoowaAAamiloo assalihati qul laas-alukum AAalayhi ajran illa almawaddata fee alqurbawaman yaqtarif hasanatan nazid lahu feeha husnaninna Allaha ghafoorun shakoor","juz":25,"page":486},{"s":42,"a":24,"key":"42:24","ar":"أَمْ يَقُولُونَ ٱفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا ۖ فَإِن يَشَإِ ٱللَّهُ يَخْتِمْ عَلَىٰ قَلْبِكَ ۗ وَيَمْحُ ٱللَّهُ ٱلْبَـٰطِلَ وَيُحِقُّ ٱلْحَقَّ بِكَلِمَـٰتِهِۦٓ ۚ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"Or do they say, \"He has invented about Allāh a lie\"? But if Allāh willed, He could seal over your heart.1 And Allāh eliminates falsehood and establishes the truth by His words. Indeed, He is Knowing of that within the breasts.","tr":"Am yaqooloona iftara AAala Allahikathiban fa-in yasha-i Allahu yakhtim AAalaqalbika wayamhu Allahu albatila wayuhiqqualhaqqa bikalimatihi innahu AAaleemun bithatiassudoor","juz":25,"page":486},{"s":42,"a":25,"key":"42:25","ar":"وَهُوَ ٱلَّذِى يَقْبَلُ ٱلتَّوْبَةَ عَنْ عِبَادِهِۦ وَيَعْفُوا۟ عَنِ ٱلسَّيِّـَٔاتِ وَيَعْلَمُ مَا تَفْعَلُونَ","en":"And it is He who accepts repentance from His servants and pardons misdeeds, and He knows what you do.","tr":"Wahuwa allathee yaqbalu attawbataAAan AAibadihi wayaAAfoo AAani assayyi-atiwayaAAlamu ma tafAAaloon","juz":25,"page":486},{"s":42,"a":26,"key":"42:26","ar":"وَيَسْتَجِيبُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ وَيَزِيدُهُم مِّن فَضْلِهِۦ ۚ وَٱلْكَـٰفِرُونَ لَهُمْ عَذَابٌ شَدِيدٌ","en":"And He answers [the supplication of] those who have believed and done righteous deeds and increases [for] them from His bounty. But the disbelievers will have a severe punishment.","tr":"Wayastajeebu allatheena amanoowaAAamiloo assalihati wayazeeduhum min fadlihiwalkafiroona lahum AAathabun shadeed","juz":25,"page":486},{"s":42,"a":27,"key":"42:27","ar":"۞ وَلَوْ بَسَطَ ٱللَّهُ ٱلرِّزْقَ لِعِبَادِهِۦ لَبَغَوْا۟ فِى ٱلْأَرْضِ وَلَـٰكِن يُنَزِّلُ بِقَدَرٍ مَّا يَشَآءُ ۚ إِنَّهُۥ بِعِبَادِهِۦ خَبِيرٌۢ بَصِيرٌ","en":"And if Allāh had extended [excessively] provision for His servants, they would have committed tyranny throughout the earth. But He sends [it] down in an amount which He wills. Indeed He is, of His servants, Aware and Seeing.","tr":"Walaw basata Allahu arrizqaliAAibadihi labaghaw fee al-ardi walakinyunazzilu biqadarin ma yashao innahu biAAibadihikhabeerun baseer","juz":25,"page":486},{"s":42,"a":28,"key":"42:28","ar":"وَهُوَ ٱلَّذِى يُنَزِّلُ ٱلْغَيْثَ مِنۢ بَعْدِ مَا قَنَطُوا۟ وَيَنشُرُ رَحْمَتَهُۥ ۚ وَهُوَ ٱلْوَلِىُّ ٱلْحَمِيدُ","en":"And it is He who sends down the rain after they had despaired and spreads His mercy. And He is the Protector, the Praiseworthy.","tr":"Wahuwa allathee yunazzilu alghaythamin baAAdi ma qanatoo wayanshuru rahmatahuwahuwa alwaliyyu alhameed","juz":25,"page":486},{"s":42,"a":29,"key":"42:29","ar":"وَمِنْ ءَايَـٰتِهِۦ خَلْقُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَثَّ فِيهِمَا مِن دَآبَّةٍ ۚ وَهُوَ عَلَىٰ جَمْعِهِمْ إِذَا يَشَآءُ قَدِيرٌ","en":"And of His signs is the creation of the heavens and earth and what He has dispersed throughout them of creatures. And He, for gathering them when He wills, is competent.","tr":"Wamin ayatihi khalqu assamawatiwal-ardi wama baththa feehima min dabbatinwahuwa AAala jamAAihim itha yashao qadeer","juz":25,"page":486},{"s":42,"a":30,"key":"42:30","ar":"وَمَآ أَصَـٰبَكُم مِّن مُّصِيبَةٍ فَبِمَا كَسَبَتْ أَيْدِيكُمْ وَيَعْفُوا۟ عَن كَثِيرٍ","en":"And whatever strikes you of disaster - it is for what your hands have earned; but He pardons much.","tr":"Wama asabakum min museebatinfabima kasabat aydeekum wayaAAfoo AAan katheer","juz":25,"page":486},{"s":42,"a":31,"key":"42:31","ar":"وَمَآ أَنتُم بِمُعْجِزِينَ فِى ٱلْأَرْضِ ۖ وَمَا لَكُم مِّن دُونِ ٱللَّهِ مِن وَلِىٍّ وَلَا نَصِيرٍ","en":"And you will not cause failure [to Allāh]1 upon the earth. And you have not besides Allāh any protector or helper.","tr":"Wama antum bimuAAjizeena fee al-ardiwama lakum min dooni Allahi min waliyyin walanaseer","juz":25,"page":486},{"s":42,"a":32,"key":"42:32","ar":"وَمِنْ ءَايَـٰتِهِ ٱلْجَوَارِ فِى ٱلْبَحْرِ كَٱلْأَعْلَـٰمِ","en":"And of His signs are the ships in the sea, like mountains.","tr":"Wamin ayatihi aljawarifee albahri kal-aAAlam","juz":25,"page":487},{"s":42,"a":33,"key":"42:33","ar":"إِن يَشَأْ يُسْكِنِ ٱلرِّيحَ فَيَظْلَلْنَ رَوَاكِدَ عَلَىٰ ظَهْرِهِۦٓ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّكُلِّ صَبَّارٍ شَكُورٍ","en":"If He willed, He could still the wind, and they would remain motionless on its surface. Indeed in that are signs for everyone patient and grateful.","tr":"In yasha/ yuskini arreehafayathlalna rawakida AAala thahrihiinna fee thalika laayatin likulli sabbarinshakoor","juz":25,"page":487},{"s":42,"a":34,"key":"42:34","ar":"أَوْ يُوبِقْهُنَّ بِمَا كَسَبُوا۟ وَيَعْفُ عَن كَثِيرٍ","en":"Or He could destroy them1 for what they earned; but He pardons much.","tr":"Aw yoobiqhunna bima kasaboo wayaAAfuAAan katheer","juz":25,"page":487},{"s":42,"a":35,"key":"42:35","ar":"وَيَعْلَمَ ٱلَّذِينَ يُجَـٰدِلُونَ فِىٓ ءَايَـٰتِنَا مَا لَهُم مِّن مَّحِيصٍ","en":"And [that is so] those who dispute concerning Our signs may know that for them there is no place of escape.","tr":"WayaAAlama allatheena yujadiloonafee ayatina ma lahum min mahees","juz":25,"page":487},{"s":42,"a":36,"key":"42:36","ar":"فَمَآ أُوتِيتُم مِّن شَىْءٍ فَمَتَـٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۖ وَمَا عِندَ ٱللَّهِ خَيْرٌ وَأَبْقَىٰ لِلَّذِينَ ءَامَنُوا۟ وَعَلَىٰ رَبِّهِمْ يَتَوَكَّلُونَ","en":"So whatever thing you have been given - it is but [for] enjoyment of the worldly life. But what is with Allāh is better and more lasting for those who have believed and upon their Lord rely","tr":"Fama ooteetum min shay-in famataAAualhayati addunya wama AAindaAllahi khayrun waabqa lillatheena amanoowaAAala rabbihim yatawakkaloon","juz":25,"page":487},{"s":42,"a":37,"key":"42:37","ar":"وَٱلَّذِينَ يَجْتَنِبُونَ كَبَـٰٓئِرَ ٱلْإِثْمِ وَٱلْفَوَٰحِشَ وَإِذَا مَا غَضِبُوا۟ هُمْ يَغْفِرُونَ","en":"And those who avoid the major sins and immoralities, and when they are angry, they forgive,","tr":"Wallatheena yajtaniboona kaba-iraal-ithmi walfawahisha wa-itha ma ghadiboohum yaghfiroon","juz":25,"page":487},{"s":42,"a":38,"key":"42:38","ar":"وَٱلَّذِينَ ٱسْتَجَابُوا۟ لِرَبِّهِمْ وَأَقَامُوا۟ ٱلصَّلَوٰةَ وَأَمْرُهُمْ شُورَىٰ بَيْنَهُمْ وَمِمَّا رَزَقْنَـٰهُمْ يُنفِقُونَ","en":"And those who have responded to their Lord and established prayer and whose affair is [determined by] consultation among themselves, and from what We have provided them, they spend,","tr":"Wallatheena istajaboolirabbihim waaqamoo assalatawaamruhum shoora baynahum wamimma razaqnahumyunfiqoon","juz":25,"page":487},{"s":42,"a":39,"key":"42:39","ar":"وَٱلَّذِينَ إِذَآ أَصَابَهُمُ ٱلْبَغْىُ هُمْ يَنتَصِرُونَ","en":"And those who, when tyranny strikes them, they retaliate [in a just manner].1","tr":"Wallatheena itha asabahumualbaghyu hum yantasiroon","juz":25,"page":487},{"s":42,"a":40,"key":"42:40","ar":"وَجَزَٰٓؤُا۟ سَيِّئَةٍ سَيِّئَةٌ مِّثْلُهَا ۖ فَمَنْ عَفَا وَأَصْلَحَ فَأَجْرُهُۥ عَلَى ٱللَّهِ ۚ إِنَّهُۥ لَا يُحِبُّ ٱلظَّـٰلِمِينَ","en":"And the retribution for an evil act is an evil one like it, but whoever pardons and makes reconciliation - his reward is [due] from Allāh. Indeed, He does not like wrongdoers.","tr":"Wajazao sayyi-atin sayyi-atun mithluhafaman AAafa waaslaha faajruhu AAalaAllahi innahu la yuhibbu aththalimeen","juz":25,"page":487},{"s":42,"a":41,"key":"42:41","ar":"وَلَمَنِ ٱنتَصَرَ بَعْدَ ظُلْمِهِۦ فَأُو۟لَـٰٓئِكَ مَا عَلَيْهِم مِّن سَبِيلٍ","en":"And whoever retaliates after having been wronged - those have not upon them any cause [for blame].","tr":"Walamani intasara baAAda thulmihifaola-ika ma AAalayhim min sabeel","juz":25,"page":487},{"s":42,"a":42,"key":"42:42","ar":"إِنَّمَا ٱلسَّبِيلُ عَلَى ٱلَّذِينَ يَظْلِمُونَ ٱلنَّاسَ وَيَبْغُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ ۚ أُو۟لَـٰٓئِكَ لَهُمْ عَذَابٌ أَلِيمٌ","en":"The cause is only against the ones who wrong the people and tyrannize upon the earth without right. Those will have a painful punishment.","tr":"Innama assabeelu AAalaallatheena yathlimoona annasawayabghoona fee al-ardi bighayri alhaqqi ola-ikalahum AAathabun aleem","juz":25,"page":487},{"s":42,"a":43,"key":"42:43","ar":"وَلَمَن صَبَرَ وَغَفَرَ إِنَّ ذَٰلِكَ لَمِنْ عَزْمِ ٱلْأُمُورِ","en":"And whoever is patient and forgives - indeed, that is of the matters [worthy] of resolve.1","tr":"Walaman sabara waghafara inna thalikalamin AAazmi al-omoor","juz":25,"page":487},{"s":42,"a":44,"key":"42:44","ar":"وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِن وَلِىٍّ مِّنۢ بَعْدِهِۦ ۗ وَتَرَى ٱلظَّـٰلِمِينَ لَمَّا رَأَوُا۟ ٱلْعَذَابَ يَقُولُونَ هَلْ إِلَىٰ مَرَدٍّ مِّن سَبِيلٍ","en":"And he whom Allāh sends astray - for him there is no protector beyond Him. And you will see the wrongdoers, when they see the punishment, saying, \"Is there for return [to the former world] any way?\"","tr":"Waman yudlili Allahu famalahu min waliyyin min baAAdihi watara aththalimeenalamma raawoo alAAathaba yaqooloona hal ilamaraddin min sabeel","juz":25,"page":487},{"s":42,"a":45,"key":"42:45","ar":"وَتَرَىٰهُمْ يُعْرَضُونَ عَلَيْهَا خَـٰشِعِينَ مِنَ ٱلذُّلِّ يَنظُرُونَ مِن طَرْفٍ خَفِىٍّ ۗ وَقَالَ ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ ٱلْخَـٰسِرِينَ ٱلَّذِينَ خَسِرُوٓا۟ أَنفُسَهُمْ وَأَهْلِيهِمْ يَوْمَ ٱلْقِيَـٰمَةِ ۗ أَلَآ إِنَّ ٱلظَّـٰلِمِينَ فِى عَذَابٍ مُّقِيمٍ","en":"And you will see them being exposed to it [i.e., the Fire], humbled from humiliation, looking from [behind] a covert glance. And those who had believed will say, \"Indeed, the [true] losers are the ones who lost themselves and their families on the Day of Resurrection. Unquestionably, the wrongdoers are in an enduring punishment.\"","tr":"Watarahum yuAAradoona AAalayhakhashiAAeena mina aththulli yanthuroonamin tarfin khafiyyin waqala allatheena amanooinna alkhasireena allatheena khasiroo anfusahumwaahleehim yawma alqiyamati ala inna aththalimeenafee AAathabin muqeem","juz":25,"page":488},{"s":42,"a":46,"key":"42:46","ar":"وَمَا كَانَ لَهُم مِّنْ أَوْلِيَآءَ يَنصُرُونَهُم مِّن دُونِ ٱللَّهِ ۗ وَمَن يُضْلِلِ ٱللَّهُ فَمَا لَهُۥ مِن سَبِيلٍ","en":"And there will not be for them any allies to aid them other than Allāh. And whoever Allāh sends astray - for him there is no way.","tr":"Wama kana lahum min awliyaayansuroonahum min dooni Allahi waman yudliliAllahu fama lahu min sabeel","juz":25,"page":488},{"s":42,"a":47,"key":"42:47","ar":"ٱسْتَجِيبُوا۟ لِرَبِّكُم مِّن قَبْلِ أَن يَأْتِىَ يَوْمٌ لَّا مَرَدَّ لَهُۥ مِنَ ٱللَّهِ ۚ مَا لَكُم مِّن مَّلْجَإٍ يَوْمَئِذٍ وَمَا لَكُم مِّن نَّكِيرٍ","en":"Respond to your Lord before a Day comes from Allāh of which there is no repelling. No refuge will you have that Day, nor for you will there be any denial.1","tr":"Istajeeboo lirabbikum min qabli an ya/tiyayawmun la maradda lahu mina Allahi ma lakummin malja-in yawma-ithin wama lakum min nakeer","juz":25,"page":488},{"s":42,"a":48,"key":"42:48","ar":"فَإِنْ أَعْرَضُوا۟ فَمَآ أَرْسَلْنَـٰكَ عَلَيْهِمْ حَفِيظًا ۖ إِنْ عَلَيْكَ إِلَّا ٱلْبَلَـٰغُ ۗ وَإِنَّآ إِذَآ أَذَقْنَا ٱلْإِنسَـٰنَ مِنَّا رَحْمَةً فَرِحَ بِهَا ۖ وَإِن تُصِبْهُمْ سَيِّئَةٌۢ بِمَا قَدَّمَتْ أَيْدِيهِمْ فَإِنَّ ٱلْإِنسَـٰنَ كَفُورٌ","en":"But if they turn away - then We have not sent you, [O Muḥammad], over them as a guardian; upon you is only [the duty of] notification. And indeed, when We let man taste mercy from Us, he rejoices in it; but if evil afflicts him for what his hands have put forth, then indeed, man is ungrateful.","tr":"Fa-in aAAradoo fama arsalnakaAAalayhim hafeethan in AAalayka illaalbalaghu wa-inna itha athaqnaal-insana minna rahmatan fariha bihawa-in tusibhum sayyi-atun bima qaddamat aydeehimfa-inna al-insana kafoor","juz":25,"page":488},{"s":42,"a":49,"key":"42:49","ar":"لِّلَّهِ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ يَخْلُقُ مَا يَشَآءُ ۚ يَهَبُ لِمَن يَشَآءُ إِنَـٰثًا وَيَهَبُ لِمَن يَشَآءُ ٱلذُّكُورَ","en":"To Allāh belongs the dominion of the heavens and the earth; He creates what He wills. He gives to whom He wills female [children], and He gives to whom He wills males.","tr":"Lillahi mulku assamawatiwal-ardi yakhluqu ma yashao yahabuliman yashao inathan wayahabu liman yashao aththukoor","juz":25,"page":488},{"s":42,"a":50,"key":"42:50","ar":"أَوْ يُزَوِّجُهُمْ ذُكْرَانًا وَإِنَـٰثًا ۖ وَيَجْعَلُ مَن يَشَآءُ عَقِيمًا ۚ إِنَّهُۥ عَلِيمٌ قَدِيرٌ","en":"Or He makes them [both] males and females, and He renders whom He wills barren. Indeed, He is Knowing and Competent.","tr":"Aw yuzawwijuhum thukrananwa-inathan wayajAAalu man yashao AAaqeeman innahuAAaleemun qadeer","juz":25,"page":488},{"s":42,"a":51,"key":"42:51","ar":"۞ وَمَا كَانَ لِبَشَرٍ أَن يُكَلِّمَهُ ٱللَّهُ إِلَّا وَحْيًا أَوْ مِن وَرَآئِ حِجَابٍ أَوْ يُرْسِلَ رَسُولًا فَيُوحِىَ بِإِذْنِهِۦ مَا يَشَآءُ ۚ إِنَّهُۥ عَلِىٌّ حَكِيمٌ","en":"And it is not for any human being that Allāh should speak to him except by revelation or from behind a partition or that He sends a messenger [i.e., angel] to reveal, by His permission, what He wills. Indeed, He is Most High and Wise.","tr":"Wama kana libasharin anyukallimahu Allahu illa wahyan aw min wara-ihijabin aw yursila rasoolan fayoohiya bi-ithnihima yashao innahu AAaliyyun hakeem","juz":25,"page":488},{"s":42,"a":52,"key":"42:52","ar":"وَكَذَٰلِكَ أَوْحَيْنَآ إِلَيْكَ رُوحًا مِّنْ أَمْرِنَا ۚ مَا كُنتَ تَدْرِى مَا ٱلْكِتَـٰبُ وَلَا ٱلْإِيمَـٰنُ وَلَـٰكِن جَعَلْنَـٰهُ نُورًا نَّهْدِى بِهِۦ مَن نَّشَآءُ مِنْ عِبَادِنَا ۚ وَإِنَّكَ لَتَهْدِىٓ إِلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"And thus We have revealed to you an inspiration of Our command [i.e., the Qur’ān]. You did not know what is the Book or [what is] faith, but We have made it a light by which We guide whom We will of Our servants. And indeed, [O Muḥammad], you guide to a straight path -","tr":"Wakathalika awhaynailayka roohan min amrina ma kunta tadree maalkitabu wala al-eemanu walakinjaAAalnahu nooran nahdee bihi man nashao min AAibadinawa-innaka latahdee ila siratin mustaqeem","juz":25,"page":489},{"s":42,"a":53,"key":"42:53","ar":"صِرَٰطِ ٱللَّهِ ٱلَّذِى لَهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۗ أَلَآ إِلَى ٱللَّهِ تَصِيرُ ٱلْأُمُورُ","en":"The path of Allāh, to whom belongs whatever is in the heavens and whatever is on the earth. Unquestionably, to Allāh do [all] matters evolve [i.e., return].","tr":"Sirati Allahi allatheelahu ma fee assamawati wamafee al-ardi ala ila Allahi taseerual-omoor","juz":25,"page":489},{"s":43,"a":1,"key":"43:1","ar":" حمٓ","en":"Ḥā, Meem.1","tr":"Ha-meem","juz":25,"page":489},{"s":43,"a":2,"key":"43:2","ar":"وَٱلْكِتَـٰبِ ٱلْمُبِينِ","en":"By the clear Book,","tr":"Walkitabi almubeen","juz":25,"page":489},{"s":43,"a":3,"key":"43:3","ar":"إِنَّا جَعَلْنَـٰهُ قُرْءَٰنًا عَرَبِيًّا لَّعَلَّكُمْ تَعْقِلُونَ","en":"Indeed, We have made it an Arabic Qur’ān that you might understand.","tr":"Inna jaAAalnahu qur-ananAAarabiyyan laAAallakum taAAqiloona","juz":25,"page":489},{"s":43,"a":4,"key":"43:4","ar":"وَإِنَّهُۥ فِىٓ أُمِّ ٱلْكِتَـٰبِ لَدَيْنَا لَعَلِىٌّ حَكِيمٌ","en":"And indeed it is, in the Mother of the Book1 with Us, exalted and full of wisdom.2","tr":"Wa-innahu fee ommi alkitabi ladaynalaAAaliyyun hakeem","juz":25,"page":489},{"s":43,"a":5,"key":"43:5","ar":"أَفَنَضْرِبُ عَنكُمُ ٱلذِّكْرَ صَفْحًا أَن كُنتُمْ قَوْمًا مُّسْرِفِينَ","en":"Then should We turn the message away, disregarding you, because you are a transgressing people?","tr":"Afanadribu AAankumu aththikrasafhan an kuntum qawman musrifeen","juz":25,"page":489},{"s":43,"a":6,"key":"43:6","ar":"وَكَمْ أَرْسَلْنَا مِن نَّبِىٍّ فِى ٱلْأَوَّلِينَ","en":"And how many a prophet We sent among the former peoples,","tr":"Wakam arsalna min nabiyyin feeal-awwaleen","juz":25,"page":489},{"s":43,"a":7,"key":"43:7","ar":"وَمَا يَأْتِيهِم مِّن نَّبِىٍّ إِلَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"But there would not come to them a prophet except that they used to ridicule him.","tr":"Wama ya/teehim min nabiyyin illakanoo bihi yastahzi-oon","juz":25,"page":489},{"s":43,"a":8,"key":"43:8","ar":"فَأَهْلَكْنَآ أَشَدَّ مِنْهُم بَطْشًا وَمَضَىٰ مَثَلُ ٱلْأَوَّلِينَ","en":"And We destroyed greater than them1 in [striking] power, and the example of the former peoples has preceded.","tr":"Faahlakna ashadda minhum batshanwamada mathalu al-awwaleen","juz":25,"page":489},{"s":43,"a":9,"key":"43:9","ar":"وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ لَيَقُولُنَّ خَلَقَهُنَّ ٱلْعَزِيزُ ٱلْعَلِيمُ","en":"And if you should ask them, \"Who has created the heavens and the earth?\" they would surely say, \"They were created by the Exalted in Might, the Knowing,\"","tr":"Wala-in saaltahum man khalaqa assamawatiwal-arda layaqoolunna khalaqahunna alAAazeezualAAaleem","juz":25,"page":489},{"s":43,"a":10,"key":"43:10","ar":"ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ مَهْدًا وَجَعَلَ لَكُمْ فِيهَا سُبُلًا لَّعَلَّكُمْ تَهْتَدُونَ","en":"[The one] who has made for you the earth a bed and made for you upon it roads that you might be guided","tr":"Allathee jaAAala lakumu al-ardamahdan wajaAAala lakum feeha subulan laAAallakum tahtadoon","juz":25,"page":489},{"s":43,"a":11,"key":"43:11","ar":"وَٱلَّذِى نَزَّلَ مِنَ ٱلسَّمَآءِ مَآءًۢ بِقَدَرٍ فَأَنشَرْنَا بِهِۦ بَلْدَةً مَّيْتًا ۚ كَذَٰلِكَ تُخْرَجُونَ","en":"And who sends down rain from the sky in measured amounts, and We revive thereby a dead land - thus will you be brought forth -","tr":"Wallathee nazzala mina assama-imaan biqadarin faansharna bihi baldatan maytan kathalikatukhrajoon","juz":25,"page":490},{"s":43,"a":12,"key":"43:12","ar":"وَٱلَّذِى خَلَقَ ٱلْأَزْوَٰجَ كُلَّهَا وَجَعَلَ لَكُم مِّنَ ٱلْفُلْكِ وَٱلْأَنْعَـٰمِ مَا تَرْكَبُونَ","en":"And who created the species, all of them, and has made for you of ships and animals those which you mount","tr":"Wallathee khalaqa al-azwajakullaha wajaAAala lakum mina alfulki wal-anAAamima tarkaboon","juz":25,"page":490},{"s":43,"a":13,"key":"43:13","ar":"لِتَسْتَوُۥا۟ عَلَىٰ ظُهُورِهِۦ ثُمَّ تَذْكُرُوا۟ نِعْمَةَ رَبِّكُمْ إِذَا ٱسْتَوَيْتُمْ عَلَيْهِ وَتَقُولُوا۟ سُبْحَـٰنَ ٱلَّذِى سَخَّرَ لَنَا هَـٰذَا وَمَا كُنَّا لَهُۥ مُقْرِنِينَ","en":"That you may settle yourselves upon their backs and then remember the favor of your Lord when you have settled upon them and say, \"Exalted is He who has subjected this to us, and we could not have [otherwise] subdued it.1","tr":"Litastawoo AAala thuhoorihithumma tathkuroo niAAmata rabbikum itha istawaytumAAalayhi wataqooloo subhana allathee sakhkhara lanahatha wama kunna lahu muqrineen","juz":25,"page":490},{"s":43,"a":14,"key":"43:14","ar":"وَإِنَّآ إِلَىٰ رَبِّنَا لَمُنقَلِبُونَ","en":"And indeed we, to our Lord, will [surely] return.\"","tr":"Wa-inna ila rabbinalamunqaliboon","juz":25,"page":490},{"s":43,"a":15,"key":"43:15","ar":"وَجَعَلُوا۟ لَهُۥ مِنْ عِبَادِهِۦ جُزْءًا ۚ إِنَّ ٱلْإِنسَـٰنَ لَكَفُورٌ مُّبِينٌ","en":"But they have attributed to Him from His servants a portion.1 Indeed, man is clearly ungrateful.","tr":"WajaAAaloo lahu min AAibadihi juz-aninna al-insana lakafoorun mubeen","juz":25,"page":490},{"s":43,"a":16,"key":"43:16","ar":"أَمِ ٱتَّخَذَ مِمَّا يَخْلُقُ بَنَاتٍ وَأَصْفَىٰكُم بِٱلْبَنِينَ","en":"Or has He taken, out of what He has created, daughters and chosen you for [having] sons?","tr":"Ami ittakhatha mimma yakhluqubanatin waasfakum bilbaneen","juz":25,"page":490},{"s":43,"a":17,"key":"43:17","ar":"وَإِذَا بُشِّرَ أَحَدُهُم بِمَا ضَرَبَ لِلرَّحْمَـٰنِ مَثَلًا ظَلَّ وَجْهُهُۥ مُسْوَدًّا وَهُوَ كَظِيمٌ","en":"And when one of them is given good tidings of that which he attributes to the Most Merciful in comparison [i.e., a daughter], his face becomes dark, and he suppresses grief.","tr":"Wa-itha bushshira ahaduhum bimadaraba lirrahmani mathalan thallawajhuhu muswaddan wahuwa katheem","juz":25,"page":490},{"s":43,"a":18,"key":"43:18","ar":"أَوَمَن يُنَشَّؤُا۟ فِى ٱلْحِلْيَةِ وَهُوَ فِى ٱلْخِصَامِ غَيْرُ مُبِينٍ","en":"So is one brought up in ornaments while being during conflict unevident1 [attributed to Allāh]?","tr":"Awaman yunashshao fee alhilyatiwahuwa fee alkhisami ghayru mubeen","juz":25,"page":490},{"s":43,"a":19,"key":"43:19","ar":"وَجَعَلُوا۟ ٱلْمَلَـٰٓئِكَةَ ٱلَّذِينَ هُمْ عِبَـٰدُ ٱلرَّحْمَـٰنِ إِنَـٰثًا ۚ أَشَهِدُوا۟ خَلْقَهُمْ ۚ سَتُكْتَبُ شَهَـٰدَتُهُمْ وَيُسْـَٔلُونَ","en":"And they described the angels, who are servants of the Most Merciful, as females. Did they witness their creation? Their testimony will be recorded, and they will be questioned.","tr":"WajaAAaloo almala-ikata allatheenahum AAibadu arrahmani inathanashahidoo khalqahum satuktabu shahadatuhum wayus-aloon","juz":25,"page":490},{"s":43,"a":20,"key":"43:20","ar":"وَقَالُوا۟ لَوْ شَآءَ ٱلرَّحْمَـٰنُ مَا عَبَدْنَـٰهُم ۗ مَّا لَهُم بِذَٰلِكَ مِنْ عِلْمٍ ۖ إِنْ هُمْ إِلَّا يَخْرُصُونَ","en":"And they said, \"If the Most Merciful had willed, we would not have worshipped them.\" They have of that no knowledge. They are not but misjudging.","tr":"Waqaloo law shaa arrahmanuma AAabadnahum ma lahum bithalika minAAilmin in hum illa yakhrusoon","juz":25,"page":490},{"s":43,"a":21,"key":"43:21","ar":"أَمْ ءَاتَيْنَـٰهُمْ كِتَـٰبًا مِّن قَبْلِهِۦ فَهُم بِهِۦ مُسْتَمْسِكُونَ","en":"Or have We given them a book before it [i.e., the Qur’ān] to which they are adhering?","tr":"Am ataynahum kitabanmin qablihi fahum bihi mustamsikoon","juz":25,"page":490},{"s":43,"a":22,"key":"43:22","ar":"بَلْ قَالُوٓا۟ إِنَّا وَجَدْنَآ ءَابَآءَنَا عَلَىٰٓ أُمَّةٍ وَإِنَّا عَلَىٰٓ ءَاثَـٰرِهِم مُّهْتَدُونَ","en":"Rather, they say, \"Indeed, we found our fathers upon a religion, and we are in their footsteps [rightly] guided.\"","tr":"Bal qaloo inna wajadna abaanaAAala ommatin wa-inna AAala atharihimmuhtadoon","juz":25,"page":490},{"s":43,"a":23,"key":"43:23","ar":"وَكَذَٰلِكَ مَآ أَرْسَلْنَا مِن قَبْلِكَ فِى قَرْيَةٍ مِّن نَّذِيرٍ إِلَّا قَالَ مُتْرَفُوهَآ إِنَّا وَجَدْنَآ ءَابَآءَنَا عَلَىٰٓ أُمَّةٍ وَإِنَّا عَلَىٰٓ ءَاثَـٰرِهِم مُّقْتَدُونَ","en":"And similarly, We did not send before you any warner into a city except that its affluent said, \"Indeed, we found our fathers upon a religion, and we are, in their footsteps, following.\"","tr":"Wakathalika ma arsalnamin qablika fee qaryatin min natheerin illa qalamutrafooha inna wajadna abaanaAAala ommatin wa-inna AAala atharihimmuqtadoon","juz":25,"page":491},{"s":43,"a":24,"key":"43:24","ar":"۞ قَـٰلَ أَوَلَوْ جِئْتُكُم بِأَهْدَىٰ مِمَّا وَجَدتُّمْ عَلَيْهِ ءَابَآءَكُمْ ۖ قَالُوٓا۟ إِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَـٰفِرُونَ","en":"[Each warner] said, \"Even if I brought you better guidance than that [religion] upon which you found your fathers?\" They said, \"Indeed we, in that with which you were sent, are disbelievers.\"","tr":"Qala awa law ji/tukum bi-ahdamimma wajadtum AAalayhi abaakum qalooinna bima orsiltum bihi kafiroon","juz":25,"page":491},{"s":43,"a":25,"key":"43:25","ar":"فَٱنتَقَمْنَا مِنْهُمْ ۖ فَٱنظُرْ كَيْفَ كَانَ عَـٰقِبَةُ ٱلْمُكَذِّبِينَ","en":"So We took retribution from them; then see how was the end of the deniers.","tr":"Fantaqamna minhum fanthurkayfa kana AAaqibatu almukaththibeen","juz":25,"page":491},{"s":43,"a":26,"key":"43:26","ar":"وَإِذْ قَالَ إِبْرَٰهِيمُ لِأَبِيهِ وَقَوْمِهِۦٓ إِنَّنِى بَرَآءٌ مِّمَّا تَعْبُدُونَ","en":"And [mention, O Muḥammad], when Abraham said to his father and his people, \"Indeed, I am disassociated from that which you worship","tr":"Wa-ith qala ibraheemuli-abeehi waqawmihi innanee baraon mimma taAAbudoon","juz":25,"page":491},{"s":43,"a":27,"key":"43:27","ar":"إِلَّا ٱلَّذِى فَطَرَنِى فَإِنَّهُۥ سَيَهْدِينِ","en":"Except for He who created me; and indeed, He will guide me.\"","tr":"Illa allathee fataraneefa-innahu sayahdeen","juz":25,"page":491},{"s":43,"a":28,"key":"43:28","ar":"وَجَعَلَهَا كَلِمَةًۢ بَاقِيَةً فِى عَقِبِهِۦ لَعَلَّهُمْ يَرْجِعُونَ","en":"And he made it1 a word remaining among his descendants that they might return [to it].","tr":"WajaAAalaha kalimatan baqiyatanfee AAaqibihi laAAallahum yarjiAAoon","juz":25,"page":491},{"s":43,"a":29,"key":"43:29","ar":"بَلْ مَتَّعْتُ هَـٰٓؤُلَآءِ وَءَابَآءَهُمْ حَتَّىٰ جَآءَهُمُ ٱلْحَقُّ وَرَسُولٌ مُّبِينٌ","en":"However, I gave enjoyment to these [people of Makkah] and their fathers1 until there came to them the truth and a clear Messenger.2","tr":"Bal mattaAAtu haola-i waabaahumhatta jaahumu alhaqqu warasoolunmubeen","juz":25,"page":491},{"s":43,"a":30,"key":"43:30","ar":"وَلَمَّا جَآءَهُمُ ٱلْحَقُّ قَالُوا۟ هَـٰذَا سِحْرٌ وَإِنَّا بِهِۦ كَـٰفِرُونَ","en":"But when the truth came to them, they said, \"This is magic, and indeed we are, concerning it, disbelievers.\"","tr":"Walamma jaahumu alhaqquqaloo hatha sihrun wa-inna bihi kafiroon","juz":25,"page":491},{"s":43,"a":31,"key":"43:31","ar":"وَقَالُوا۟ لَوْلَا نُزِّلَ هَـٰذَا ٱلْقُرْءَانُ عَلَىٰ رَجُلٍ مِّنَ ٱلْقَرْيَتَيْنِ عَظِيمٍ","en":"And they said, \"Why was this Qur’ān not sent down upon a great man from [one of] the two cities?\"1","tr":"Waqaloo lawla nuzzila hathaalqur-anu AAala rajulin mina alqaryatayni AAatheem","juz":25,"page":491},{"s":43,"a":32,"key":"43:32","ar":"أَهُمْ يَقْسِمُونَ رَحْمَتَ رَبِّكَ ۚ نَحْنُ قَسَمْنَا بَيْنَهُم مَّعِيشَتَهُمْ فِى ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَرَفَعْنَا بَعْضَهُمْ فَوْقَ بَعْضٍ دَرَجَـٰتٍ لِّيَتَّخِذَ بَعْضُهُم بَعْضًا سُخْرِيًّا ۗ وَرَحْمَتُ رَبِّكَ خَيْرٌ مِّمَّا يَجْمَعُونَ","en":"Do they distribute the mercy of your Lord? It is We who have apportioned among them their livelihood in the life of this world and have raised some of them above others in degrees [of rank] that they may make use of one another for service. But the mercy of your Lord is better than whatever they accumulate.","tr":"Ahum yaqsimoona rahmata rabbika nahnuqasamna baynahum maAAeeshatahum fee alhayatiaddunya warafaAAna baAAdahum fawqabaAAdin darajatin liyattakhitha baAAduhumbaAAdan sukhriyyan warahmatu rabbika khayrun mimmayajmaAAoon","juz":25,"page":491},{"s":43,"a":33,"key":"43:33","ar":"وَلَوْلَآ أَن يَكُونَ ٱلنَّاسُ أُمَّةً وَٰحِدَةً لَّجَعَلْنَا لِمَن يَكْفُرُ بِٱلرَّحْمَـٰنِ لِبُيُوتِهِمْ سُقُفًا مِّن فِضَّةٍ وَمَعَارِجَ عَلَيْهَا يَظْهَرُونَ","en":"And if it were not that the people would become one community [of disbelievers],1 We would have made for those who disbelieve in the Most Merciful - for their houses - ceilings and stairways of silver upon which to mount.","tr":"Walawla an yakoona annasuommatan wahidatan lajaAAalna liman yakfuru birrahmanilibuyootihim suqufan min fiddatin wamaAAarijaAAalayha yathharoon","juz":25,"page":491},{"s":43,"a":34,"key":"43:34","ar":"وَلِبُيُوتِهِمْ أَبْوَٰبًا وَسُرُرًا عَلَيْهَا يَتَّكِـُٔونَ","en":"And for their houses - doors and couches [of silver] upon which to recline","tr":"Walibuyootihim abwaban wasururanAAalayha yattaki-oon","juz":25,"page":492},{"s":43,"a":35,"key":"43:35","ar":"وَزُخْرُفًا ۚ وَإِن كُلُّ ذَٰلِكَ لَمَّا مَتَـٰعُ ٱلْحَيَوٰةِ ٱلدُّنْيَا ۚ وَٱلْـَٔاخِرَةُ عِندَ رَبِّكَ لِلْمُتَّقِينَ","en":"And gold ornament. But all that is not but the enjoyment of worldly life. And the Hereafter with your Lord is for the righteous.","tr":"Wazukhrufan wa-in kullu thalika lammamataAAu alhayati addunya wal-akhiratuAAinda rabbika lilmuttaqeen","juz":25,"page":492},{"s":43,"a":36,"key":"43:36","ar":"وَمَن يَعْشُ عَن ذِكْرِ ٱلرَّحْمَـٰنِ نُقَيِّضْ لَهُۥ شَيْطَـٰنًا فَهُوَ لَهُۥ قَرِينٌ","en":"And whoever is blinded from remembrance of the Most Merciful - We appoint for him a devil, and he is to him a companion.","tr":"Waman yaAAshu AAan thikri arrahmaninuqayyid lahu shaytanan fahuwa lahu qareen","juz":25,"page":492},{"s":43,"a":37,"key":"43:37","ar":"وَإِنَّهُمْ لَيَصُدُّونَهُمْ عَنِ ٱلسَّبِيلِ وَيَحْسَبُونَ أَنَّهُم مُّهْتَدُونَ","en":"And indeed, they [i.e., the devils] avert them from the way [of guidance] while they think that they are [rightly] guided","tr":"Wa-innahum layasuddoonahum AAani assabeeliwayahsaboona annahum muhtadoon","juz":25,"page":492},{"s":43,"a":38,"key":"43:38","ar":"حَتَّىٰٓ إِذَا جَآءَنَا قَالَ يَـٰلَيْتَ بَيْنِى وَبَيْنَكَ بُعْدَ ٱلْمَشْرِقَيْنِ فَبِئْسَ ٱلْقَرِينُ","en":"Until, when he comes to Us [at Judgement], he says [to his companion], \"How I wish there was between me and you the distance between the east and west; and what a wretched companion.\"","tr":"Hatta itha jaanaqala ya layta baynee wabaynaka buAAda almashriqaynifabi/sa alqareen","juz":25,"page":492},{"s":43,"a":39,"key":"43:39","ar":"وَلَن يَنفَعَكُمُ ٱلْيَوْمَ إِذ ظَّلَمْتُمْ أَنَّكُمْ فِى ٱلْعَذَابِ مُشْتَرِكُونَ","en":"And never will it benefit you that Day, when you have wronged, that you are [all] sharing in the punishment.","tr":"Walan yanfaAAakumu alyawma ith thalamtumannakum fee alAAathabi mushtarikoon","juz":25,"page":492},{"s":43,"a":40,"key":"43:40","ar":"أَفَأَنتَ تُسْمِعُ ٱلصُّمَّ أَوْ تَهْدِى ٱلْعُمْىَ وَمَن كَانَ فِى ضَلَـٰلٍ مُّبِينٍ","en":"Then will you make the deaf hear, [O Muḥammad], or guide the blind or he who is in clear error?","tr":"Afaanta tusmiAAu assumma awtahdee alAAumya waman kana fee dalalinmubeen","juz":25,"page":492},{"s":43,"a":41,"key":"43:41","ar":"فَإِمَّا نَذْهَبَنَّ بِكَ فَإِنَّا مِنْهُم مُّنتَقِمُونَ","en":"And whether [or not] We take you away [in death], indeed, We will take retribution upon them.","tr":"Fa-imma nathhabanna bikafa-inna minhum muntaqimoon","juz":25,"page":492},{"s":43,"a":42,"key":"43:42","ar":"أَوْ نُرِيَنَّكَ ٱلَّذِى وَعَدْنَـٰهُمْ فَإِنَّا عَلَيْهِم مُّقْتَدِرُونَ","en":"Or whether [or not] We show you that which We have promised them, indeed, We are Perfect in Ability.","tr":"Aw nuriyannaka allathee waAAadnahumfa-inna AAalayhim muqtadiroon","juz":25,"page":492},{"s":43,"a":43,"key":"43:43","ar":"فَٱسْتَمْسِكْ بِٱلَّذِىٓ أُوحِىَ إِلَيْكَ ۖ إِنَّكَ عَلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"So adhere to that which is revealed to you. Indeed, you are on a straight path.","tr":"Fastamsik billatheeoohiya ilayka innaka AAala siratinmustaqeem","juz":25,"page":492},{"s":43,"a":44,"key":"43:44","ar":"وَإِنَّهُۥ لَذِكْرٌ لَّكَ وَلِقَوْمِكَ ۖ وَسَوْفَ تُسْـَٔلُونَ","en":"And indeed, it is a remembrance1 for you and your people, and you [all] are going to be questioned.","tr":"Wa-innahu lathikrun laka waliqawmikawasawfa tus-aloon","juz":25,"page":492},{"s":43,"a":45,"key":"43:45","ar":"وَسْـَٔلْ مَنْ أَرْسَلْنَا مِن قَبْلِكَ مِن رُّسُلِنَآ أَجَعَلْنَا مِن دُونِ ٱلرَّحْمَـٰنِ ءَالِهَةً يُعْبَدُونَ","en":"And ask those We sent before you of Our messengers; have We made besides the Most Merciful deities to be worshipped?","tr":"Was-al man arsalna minqablika min rusulina ajaAAalna min dooni arrahmanialihatan yuAAbadoon","juz":25,"page":492},{"s":43,"a":46,"key":"43:46","ar":"وَلَقَدْ أَرْسَلْنَا مُوسَىٰ بِـَٔايَـٰتِنَآ إِلَىٰ فِرْعَوْنَ وَمَلَإِي۟هِۦ فَقَالَ إِنِّى رَسُولُ رَبِّ ٱلْعَـٰلَمِينَ","en":"And certainly did We send Moses with Our signs to Pharaoh and his establishment, and he said, \"Indeed, I am the messenger of the Lord of the worlds.\"","tr":"Walaqad arsalna moosa bi-ayatinaila firAAawna wamala-ihi faqala innee rasoolu rabbialAAalameen","juz":25,"page":492},{"s":43,"a":47,"key":"43:47","ar":"فَلَمَّا جَآءَهُم بِـَٔايَـٰتِنَآ إِذَا هُم مِّنْهَا يَضْحَكُونَ","en":"But when he brought them Our signs, at once they laughed at them.","tr":"Falamma jaahum bi-ayatinaitha hum minha yadhakoon","juz":25,"page":492},{"s":43,"a":48,"key":"43:48","ar":"وَمَا نُرِيهِم مِّنْ ءَايَةٍ إِلَّا هِىَ أَكْبَرُ مِنْ أُخْتِهَا ۖ وَأَخَذْنَـٰهُم بِٱلْعَذَابِ لَعَلَّهُمْ يَرْجِعُونَ","en":"And We showed them not a sign except that it was greater than its sister, and We seized them with affliction that perhaps they might return [to faith].","tr":"Wama nureehim min ayatin illahiya akbaru min okhtiha waakhathnahum bilAAathabilaAAallahum yarjiAAoon","juz":25,"page":493},{"s":43,"a":49,"key":"43:49","ar":"وَقَالُوا۟ يَـٰٓأَيُّهَ ٱلسَّاحِرُ ٱدْعُ لَنَا رَبَّكَ بِمَا عَهِدَ عِندَكَ إِنَّنَا لَمُهْتَدُونَ","en":"And they said [to Moses], \"O magician, invoke for us your Lord by what He has promised you. Indeed, we will be guided.\"","tr":"Waqaloo ya ayyuha asahiruodAAu lana rabbaka bima AAahida AAindaka innanalamuhtadoon","juz":25,"page":493},{"s":43,"a":50,"key":"43:50","ar":"فَلَمَّا كَشَفْنَا عَنْهُمُ ٱلْعَذَابَ إِذَا هُمْ يَنكُثُونَ","en":"But when We removed from them the affliction, at once they broke their word.","tr":"Falamma kashafna AAanhumualAAathaba itha hum yankuthoon","juz":25,"page":493},{"s":43,"a":51,"key":"43:51","ar":"وَنَادَىٰ فِرْعَوْنُ فِى قَوْمِهِۦ قَالَ يَـٰقَوْمِ أَلَيْسَ لِى مُلْكُ مِصْرَ وَهَـٰذِهِ ٱلْأَنْهَـٰرُ تَجْرِى مِن تَحْتِىٓ ۖ أَفَلَا تُبْصِرُونَ","en":"And Pharaoh called out among his people; he said, \"O my people, does not the kingdom of Egypt belong to me, and these rivers flowing beneath me; then do you not see?","tr":"Wanada firAAawnu fee qawmihi qalaya qawmi alaysa lee mulku misra wahathihial-anharu tajree min tahtee afala tubsiroon","juz":25,"page":493},{"s":43,"a":52,"key":"43:52","ar":"أَمْ أَنَا۠ خَيْرٌ مِّنْ هَـٰذَا ٱلَّذِى هُوَ مَهِينٌ وَلَا يَكَادُ يُبِينُ","en":"Or am I [not] better than this one [i.e., Moses] who is insignificant and hardly makes himself clear?1","tr":"Am ana khayrun min hatha allatheehuwa maheenun wala yakadu yubeen","juz":25,"page":493},{"s":43,"a":53,"key":"43:53","ar":"فَلَوْلَآ أُلْقِىَ عَلَيْهِ أَسْوِرَةٌ مِّن ذَهَبٍ أَوْ جَآءَ مَعَهُ ٱلْمَلَـٰٓئِكَةُ مُقْتَرِنِينَ","en":"Then why have there not been placed upon him bracelets of gold or come with him the angels in conjunction?\"","tr":"Falawla olqiya AAalayhi aswiratun minthahabin aw jaa maAAahu almala-ikatumuqtarineen","juz":25,"page":493},{"s":43,"a":54,"key":"43:54","ar":"فَٱسْتَخَفَّ قَوْمَهُۥ فَأَطَاعُوهُ ۚ إِنَّهُمْ كَانُوا۟ قَوْمًا فَـٰسِقِينَ","en":"So he bluffed his people, and they obeyed him. Indeed, they were [themselves] a people defiantly disobedient [of Allāh].","tr":"Fastakhaffa qawmahu faataAAoohuinnahum kanoo qawman fasiqeen","juz":25,"page":493},{"s":43,"a":55,"key":"43:55","ar":"فَلَمَّآ ءَاسَفُونَا ٱنتَقَمْنَا مِنْهُمْ فَأَغْرَقْنَـٰهُمْ أَجْمَعِينَ","en":"And when they angered Us, We took retribution from them and drowned them all.","tr":"Falamma asafoonaintaqamna minhum faaghraqnahum ajmaAAeen","juz":25,"page":493},{"s":43,"a":56,"key":"43:56","ar":"فَجَعَلْنَـٰهُمْ سَلَفًا وَمَثَلًا لِّلْـَٔاخِرِينَ","en":"And We made them a precedent and an example for the later peoples.","tr":"FajaAAalnahum salafan wamathalan lil-akhireen","juz":25,"page":493},{"s":43,"a":57,"key":"43:57","ar":"۞ وَلَمَّا ضُرِبَ ٱبْنُ مَرْيَمَ مَثَلًا إِذَا قَوْمُكَ مِنْهُ يَصِدُّونَ","en":"And when the son of Mary was presented as an example,1 immediately your people laughed aloud.","tr":"Walamma duriba ibnu maryamamathalan itha qawmuka minhu yasiddoon","juz":25,"page":493},{"s":43,"a":58,"key":"43:58","ar":"وَقَالُوٓا۟ ءَأَـٰلِهَتُنَا خَيْرٌ أَمْ هُوَ ۚ مَا ضَرَبُوهُ لَكَ إِلَّا جَدَلًۢا ۚ بَلْ هُمْ قَوْمٌ خَصِمُونَ","en":"And they said, \"Are our gods better, or is he?\"1 They did not present it [i.e., the comparison] except for [mere] argument. But, [in fact], they are a people prone to dispute.","tr":"Waqaloo aalihatunakhayrun am huwa ma daraboohu laka illajadalan bal hum qawmun khasimoon","juz":25,"page":493},{"s":43,"a":59,"key":"43:59","ar":"إِنْ هُوَ إِلَّا عَبْدٌ أَنْعَمْنَا عَلَيْهِ وَجَعَلْنَـٰهُ مَثَلًا لِّبَنِىٓ إِسْرَٰٓءِيلَ","en":"He [i.e., Jesus] was not but a servant upon whom We bestowed favor, and We made him an example for the Children of Israel.","tr":"In huwa illa AAabdun anAAamnaAAalayhi wajaAAalnahu mathalan libanee isra-eel","juz":25,"page":493},{"s":43,"a":60,"key":"43:60","ar":"وَلَوْ نَشَآءُ لَجَعَلْنَا مِنكُم مَّلَـٰٓئِكَةً فِى ٱلْأَرْضِ يَخْلُفُونَ","en":"And if We willed, We could have made [instead] of you angels succeeding [one another]1 on the earth.","tr":"Walaw nashao lajaAAalna minkummala-ikatan fee al-ardi yakhlufoon","juz":25,"page":493},{"s":43,"a":61,"key":"43:61","ar":"وَإِنَّهُۥ لَعِلْمٌ لِّلسَّاعَةِ فَلَا تَمْتَرُنَّ بِهَا وَٱتَّبِعُونِ ۚ هَـٰذَا صِرَٰطٌ مُّسْتَقِيمٌ","en":"And indeed, he [i.e., Jesus] will be [a sign for] knowledge of the Hour, so be not in doubt of it, and follow Me.1 This is a straight path.","tr":"Wa-innahu laAAilmun lissaAAatifala tamtarunna biha wattabiAAooni hathasiratun mustaqeem","juz":25,"page":494},{"s":43,"a":62,"key":"43:62","ar":"وَلَا يَصُدَّنَّكُمُ ٱلشَّيْطَـٰنُ ۖ إِنَّهُۥ لَكُمْ عَدُوٌّ مُّبِينٌ","en":"And never let Satan avert you. Indeed, he is to you a clear enemy.","tr":"Wala yasuddannakumu ashshaytanuinnahu lakum AAaduwwun mubeen","juz":25,"page":494},{"s":43,"a":63,"key":"43:63","ar":"وَلَمَّا جَآءَ عِيسَىٰ بِٱلْبَيِّنَـٰتِ قَالَ قَدْ جِئْتُكُم بِٱلْحِكْمَةِ وَلِأُبَيِّنَ لَكُم بَعْضَ ٱلَّذِى تَخْتَلِفُونَ فِيهِ ۖ فَٱتَّقُوا۟ ٱللَّهَ وَأَطِيعُونِ","en":"And when Jesus brought clear proofs, he said, \"I have come to you with wisdom [i.e., prophethood] and to make clear to you some of that over which you differ, so fear Allāh and obey me.","tr":"Walamma jaa AAeesa bilbayyinatiqala qad ji/tukum bilhikmati wali-obayyinalakum baAAda allathee takhtalifoona feehi fattaqooAllaha waateeAAoon","juz":25,"page":494},{"s":43,"a":64,"key":"43:64","ar":"إِنَّ ٱللَّهَ هُوَ رَبِّى وَرَبُّكُمْ فَٱعْبُدُوهُ ۚ هَـٰذَا صِرَٰطٌ مُّسْتَقِيمٌ","en":"Indeed, Allāh is my Lord and your Lord, so worship Him. This is a straight path.\"","tr":"Inna Allaha huwa rabbee warabbukum faAAbudoohuhatha siratun mustaqeem","juz":25,"page":494},{"s":43,"a":65,"key":"43:65","ar":"فَٱخْتَلَفَ ٱلْأَحْزَابُ مِنۢ بَيْنِهِمْ ۖ فَوَيْلٌ لِّلَّذِينَ ظَلَمُوا۟ مِنْ عَذَابِ يَوْمٍ أَلِيمٍ","en":"But the denominations from among them differed [and separated], so woe to those who have wronged from the punishment of a painful Day.","tr":"Fakhtalafa al-ahzabumin baynihim fawaylun lillatheena thalamoomin AAathabi yawmin aleem","juz":25,"page":494},{"s":43,"a":66,"key":"43:66","ar":"هَلْ يَنظُرُونَ إِلَّا ٱلسَّاعَةَ أَن تَأْتِيَهُم بَغْتَةً وَهُمْ لَا يَشْعُرُونَ","en":"Are they waiting except for the Hour to come upon them suddenly while they perceive not?","tr":"Hal yanthuroona illa assaAAataan ta/tiyahum baghtatan wahum la yashAAuroon","juz":25,"page":494},{"s":43,"a":67,"key":"43:67","ar":"ٱلْأَخِلَّآءُ يَوْمَئِذٍۭ بَعْضُهُمْ لِبَعْضٍ عَدُوٌّ إِلَّا ٱلْمُتَّقِينَ","en":"Close friends, that Day, will be enemies to each other, except for the righteous","tr":"Al-akhillao yawma-ithin baAAduhumlibaAAdin AAaduwwun illa almuttaqeen","juz":25,"page":494},{"s":43,"a":68,"key":"43:68","ar":"يَـٰعِبَادِ لَا خَوْفٌ عَلَيْكُمُ ٱلْيَوْمَ وَلَآ أَنتُمْ تَحْزَنُونَ","en":"[To whom Allāh will say], \"O My servants, no fear will there be concerning you this Day, nor will you grieve,","tr":"Ya AAibadi la khawfunAAalaykumu alyawma wala antum tahzanoon","juz":25,"page":494},{"s":43,"a":69,"key":"43:69","ar":"ٱلَّذِينَ ءَامَنُوا۟ بِـَٔايَـٰتِنَا وَكَانُوا۟ مُسْلِمِينَ","en":"[You] who believed in Our verses and were Muslims.","tr":"Allatheena amanoo bi-ayatinawakanoo muslimeen","juz":25,"page":494},{"s":43,"a":70,"key":"43:70","ar":"ٱدْخُلُوا۟ ٱلْجَنَّةَ أَنتُمْ وَأَزْوَٰجُكُمْ تُحْبَرُونَ","en":"Enter Paradise, you and your kinds,1 delighted.\"","tr":"Odkhuloo aljannata antum waazwajukumtuhbaroon","juz":25,"page":494},{"s":43,"a":71,"key":"43:71","ar":"يُطَافُ عَلَيْهِم بِصِحَافٍ مِّن ذَهَبٍ وَأَكْوَابٍ ۖ وَفِيهَا مَا تَشْتَهِيهِ ٱلْأَنفُسُ وَتَلَذُّ ٱلْأَعْيُنُ ۖ وَأَنتُمْ فِيهَا خَـٰلِدُونَ","en":"Circulated among them will be plates and vessels of gold. And therein is whatever the souls desire and [what] delights the eyes, and you will abide therein eternally.","tr":"Yutafu AAalayhim bisihafinmin thahabin waakwabin wafeeha matashtaheehi al-anfusu watalaththu al-aAAyunu waantum feehakhalidoon","juz":25,"page":494},{"s":43,"a":72,"key":"43:72","ar":"وَتِلْكَ ٱلْجَنَّةُ ٱلَّتِىٓ أُورِثْتُمُوهَا بِمَا كُنتُمْ تَعْمَلُونَ","en":"And that is Paradise which you are made to inherit for what you used to do.","tr":"Watilka aljannatu allatee oorithtumoohabima kuntum taAAmaloon","juz":25,"page":494},{"s":43,"a":73,"key":"43:73","ar":"لَكُمْ فِيهَا فَـٰكِهَةٌ كَثِيرَةٌ مِّنْهَا تَأْكُلُونَ","en":"For you therein is much fruit1 from which you will eat.","tr":"Lakum feeha fakihatunkatheeratun minha ta/kuloon","juz":25,"page":494},{"s":43,"a":74,"key":"43:74","ar":"إِنَّ ٱلْمُجْرِمِينَ فِى عَذَابِ جَهَنَّمَ خَـٰلِدُونَ","en":"Indeed, the criminals will be in the punishment of Hell, abiding eternally.","tr":"Inna almujrimeena fee AAathabijahannama khalidoon","juz":25,"page":495},{"s":43,"a":75,"key":"43:75","ar":"لَا يُفَتَّرُ عَنْهُمْ وَهُمْ فِيهِ مُبْلِسُونَ","en":"It will not be allowed to subside for them, and they, therein, are in despair.","tr":"La yufattaru AAanhum wahum feehimublisoon","juz":25,"page":495},{"s":43,"a":76,"key":"43:76","ar":"وَمَا ظَلَمْنَـٰهُمْ وَلَـٰكِن كَانُوا۟ هُمُ ٱلظَّـٰلِمِينَ","en":"And We did not wrong them, but it was they who were the wrongdoers.","tr":"Wama thalamnahumwalakin kanoo humu aththalimeen","juz":25,"page":495},{"s":43,"a":77,"key":"43:77","ar":"وَنَادَوْا۟ يَـٰمَـٰلِكُ لِيَقْضِ عَلَيْنَا رَبُّكَ ۖ قَالَ إِنَّكُم مَّـٰكِثُونَ","en":"And they will call, \"O Mālik,1 let your Lord put an end to us!\" He will say, \"Indeed, you will remain.\"","tr":"Wanadaw ya maliku liyaqdiAAalayna rabbuka qala innakum makithoon","juz":25,"page":495},{"s":43,"a":78,"key":"43:78","ar":"لَقَدْ جِئْنَـٰكُم بِٱلْحَقِّ وَلَـٰكِنَّ أَكْثَرَكُمْ لِلْحَقِّ كَـٰرِهُونَ","en":"We had certainly brought you the truth, but most of you, to the truth, were averse.","tr":"Laqad ji/nakum bilhaqqiwalakinna aktharakum lilhaqqi karihoon","juz":25,"page":495},{"s":43,"a":79,"key":"43:79","ar":"أَمْ أَبْرَمُوٓا۟ أَمْرًا فَإِنَّا مُبْرِمُونَ","en":"Or have they devised [some] affair?1 But indeed, We are devising [a plan].","tr":"Am abramoo amran fa-inna mubrimoon","juz":25,"page":495},{"s":43,"a":80,"key":"43:80","ar":"أَمْ يَحْسَبُونَ أَنَّا لَا نَسْمَعُ سِرَّهُمْ وَنَجْوَىٰهُم ۚ بَلَىٰ وَرُسُلُنَا لَدَيْهِمْ يَكْتُبُونَ","en":"Or do they think that We hear not their secrets and their private conversations? Yes, [We do], and Our messengers [i.e., angels] are with them recording.","tr":"Am yahsaboona anna lanasmaAAu sirrahum wanajwahum bala warusulunaladayhim yaktuboon","juz":25,"page":495},{"s":43,"a":81,"key":"43:81","ar":"قُلْ إِن كَانَ لِلرَّحْمَـٰنِ وَلَدٌ فَأَنَا۠ أَوَّلُ ٱلْعَـٰبِدِينَ","en":"Say, [O Muḥammad], \"If the Most Merciful had a son, then I would be the first of [his] worshippers.\"1","tr":"Qul in kana lirrahmaniwaladun faana awwalu alAAabideen","juz":25,"page":495},{"s":43,"a":82,"key":"43:82","ar":"سُبْحَـٰنَ رَبِّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ رَبِّ ٱلْعَرْشِ عَمَّا يَصِفُونَ","en":"Exalted is the Lord of the heavens and the earth, Lord of the Throne, above what they describe.","tr":"Subhana rabbi assamawatiwal-ardi rabbi alAAarshi AAamma yasifoon","juz":25,"page":495},{"s":43,"a":83,"key":"43:83","ar":"فَذَرْهُمْ يَخُوضُوا۟ وَيَلْعَبُوا۟ حَتَّىٰ يُلَـٰقُوا۟ يَوْمَهُمُ ٱلَّذِى يُوعَدُونَ","en":"So leave them to converse vainly and amuse themselves until they meet their Day which they are promised.","tr":"Fatharhum yakhoodoowayalAAaboo hatta yulaqoo yawmahumu allatheeyooAAadoon","juz":25,"page":495},{"s":43,"a":84,"key":"43:84","ar":"وَهُوَ ٱلَّذِى فِى ٱلسَّمَآءِ إِلَـٰهٌ وَفِى ٱلْأَرْضِ إِلَـٰهٌ ۚ وَهُوَ ٱلْحَكِيمُ ٱلْعَلِيمُ","en":"And it is He [i.e., Allāh] who is [the only] deity in the heaven, and on the earth [the only] deity. And He is the Wise, the Knowing.","tr":"Wahuwa allathee fee assama-iilahun wafee al-ardi ilahun wahuwa alhakeemualAAaleem","juz":25,"page":495},{"s":43,"a":85,"key":"43:85","ar":"وَتَبَارَكَ ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا وَعِندَهُۥ عِلْمُ ٱلسَّاعَةِ وَإِلَيْهِ تُرْجَعُونَ","en":"And blessed is He to whom belongs the dominion of the heavens and the earth and whatever is between them and with whom is knowledge of the Hour and to whom you will be returned.","tr":"Watabaraka allathee lahu mulkuassamawati wal-ardi wamabaynahuma waAAindahu AAilmu assaAAatiwa-ilayhi turjaAAoon","juz":25,"page":495},{"s":43,"a":86,"key":"43:86","ar":"وَلَا يَمْلِكُ ٱلَّذِينَ يَدْعُونَ مِن دُونِهِ ٱلشَّفَـٰعَةَ إِلَّا مَن شَهِدَ بِٱلْحَقِّ وَهُمْ يَعْلَمُونَ","en":"And those they invoke1 besides Him do not possess [power of] intercession; but only those who testify to the truth [can benefit], and they know.2","tr":"Wala yamliku allatheenayadAAoona min doonihi ashshafaAAata illaman shahida bilhaqqi wahum yaAAlamoon","juz":25,"page":495},{"s":43,"a":87,"key":"43:87","ar":"وَلَئِن سَأَلْتَهُم مَّنْ خَلَقَهُمْ لَيَقُولُنَّ ٱللَّهُ ۖ فَأَنَّىٰ يُؤْفَكُونَ","en":"And if you asked them1 who created them, they would surely say, \"Allāh.\" So how are they deluded?","tr":"Wala-in saaltahum man khalaqahumlayaqoolunna Allahu faanna yu/fakoon","juz":25,"page":495},{"s":43,"a":88,"key":"43:88","ar":"وَقِيلِهِۦ يَـٰرَبِّ إِنَّ هَـٰٓؤُلَآءِ قَوْمٌ لَّا يُؤْمِنُونَ","en":"And [Allāh acknowledges] his saying,1 \"O my Lord, indeed these are a people who do not believe.\"","tr":"Waqeelihi ya rabbi inna haola-iqawmun la yu/minoon","juz":25,"page":495},{"s":43,"a":89,"key":"43:89","ar":"فَٱصْفَحْ عَنْهُمْ وَقُلْ سَلَـٰمٌ ۚ فَسَوْفَ يَعْلَمُونَ","en":"So turn aside from them and say, \"Peace.\"1 But they are going to know.","tr":"Fasfah AAanhum waqulsalamun fasawfa yaAAlamoon","juz":25,"page":495},{"s":44,"a":1,"key":"44:1","ar":" حمٓ","en":"Ḥā, Meem.1","tr":"Ha-meem","juz":25,"page":496},{"s":44,"a":2,"key":"44:2","ar":"وَٱلْكِتَـٰبِ ٱلْمُبِينِ","en":"By the clear Book,","tr":"Walkitabi almubeen","juz":25,"page":496},{"s":44,"a":3,"key":"44:3","ar":"إِنَّآ أَنزَلْنَـٰهُ فِى لَيْلَةٍ مُّبَـٰرَكَةٍ ۚ إِنَّا كُنَّا مُنذِرِينَ","en":"Indeed, We sent it down during a blessed night.1 Indeed, We were to warn [mankind].","tr":"Inna anzalnahu fee laylatin mubarakatininna kunna munthireen","juz":25,"page":496},{"s":44,"a":4,"key":"44:4","ar":"فِيهَا يُفْرَقُ كُلُّ أَمْرٍ حَكِيمٍ","en":"Therein [i.e., on that night] is made distinct1 every precise matter -","tr":"Feeha yufraqu kullu amrin hakeem","juz":25,"page":496},{"s":44,"a":5,"key":"44:5","ar":"أَمْرًا مِّنْ عِندِنَآ ۚ إِنَّا كُنَّا مُرْسِلِينَ","en":"[Every] matter [proceeding] from Us. Indeed, We were to send [a messenger]","tr":"Amran min AAindina inna kunnamursileen","juz":25,"page":496},{"s":44,"a":6,"key":"44:6","ar":"رَحْمَةً مِّن رَّبِّكَ ۚ إِنَّهُۥ هُوَ ٱلسَّمِيعُ ٱلْعَلِيمُ","en":"As mercy from your Lord. Indeed, He is the Hearing, the Knowing,","tr":"Rahmatan min rabbika innahu huwa assameeAAualAAaleem","juz":25,"page":496},{"s":44,"a":7,"key":"44:7","ar":"رَبِّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَآ ۖ إِن كُنتُم مُّوقِنِينَ","en":"Lord of the heavens and the earth and that between them, if you would be certain.","tr":"Rabbi assamawati wal-ardiwama baynahuma in kuntum mooqineen","juz":25,"page":496},{"s":44,"a":8,"key":"44:8","ar":"لَآ إِلَـٰهَ إِلَّا هُوَ يُحْىِۦ وَيُمِيتُ ۖ رَبُّكُمْ وَرَبُّ ءَابَآئِكُمُ ٱلْأَوَّلِينَ","en":"There is no deity except Him; He gives life and causes death. [He is] your Lord and the Lord of your first forefathers.","tr":"La ilaha illa huwa yuhyeewayumeetu rabbukum warabbu aba-ikumu al-awwaleen","juz":25,"page":496},{"s":44,"a":9,"key":"44:9","ar":"بَلْ هُمْ فِى شَكٍّ يَلْعَبُونَ","en":"But they are in doubt, amusing themselves.","tr":"Bal hum fee shakkin yalAAaboon","juz":25,"page":496},{"s":44,"a":10,"key":"44:10","ar":"فَٱرْتَقِبْ يَوْمَ تَأْتِى ٱلسَّمَآءُ بِدُخَانٍ مُّبِينٍ","en":"Then watch for the Day when the sky will bring a visible smoke","tr":"Fartaqib yawma ta/tee assamaobidukhanin mubeen","juz":25,"page":496},{"s":44,"a":11,"key":"44:11","ar":"يَغْشَى ٱلنَّاسَ ۖ هَـٰذَا عَذَابٌ أَلِيمٌ","en":"Covering the people; this is a painful torment.","tr":"Yaghsha annasa hathaAAathabun aleem","juz":25,"page":496},{"s":44,"a":12,"key":"44:12","ar":"رَّبَّنَا ٱكْشِفْ عَنَّا ٱلْعَذَابَ إِنَّا مُؤْمِنُونَ","en":"[They will say], \"Our Lord, remove from us the torment; indeed, we are believers.\"","tr":"Rabbana ikshif AAanna alAAathabainna mu/minoon","juz":25,"page":496},{"s":44,"a":13,"key":"44:13","ar":"أَنَّىٰ لَهُمُ ٱلذِّكْرَىٰ وَقَدْ جَآءَهُمْ رَسُولٌ مُّبِينٌ","en":"How will there be for them a reminder [at that time]? And there had come to them a clear Messenger.","tr":"Anna lahumu aththikrawaqad jaahum rasoolun mubeen","juz":25,"page":496},{"s":44,"a":14,"key":"44:14","ar":"ثُمَّ تَوَلَّوْا۟ عَنْهُ وَقَالُوا۟ مُعَلَّمٌ مَّجْنُونٌ","en":"Then they turned away from him and said, \"[He was] taught [and is] a madman.\"","tr":"Thumma tawallaw AAanhu waqaloomuAAallamun majnoon","juz":25,"page":496},{"s":44,"a":15,"key":"44:15","ar":"إِنَّا كَاشِفُوا۟ ٱلْعَذَابِ قَلِيلًا ۚ إِنَّكُمْ عَآئِدُونَ","en":"Indeed, We will remove the torment for a little. Indeed, you [disbelievers] will return [to disbelief].","tr":"Inna kashifoo alAAathabiqaleelan innakum AAa-idoon","juz":25,"page":496},{"s":44,"a":16,"key":"44:16","ar":"يَوْمَ نَبْطِشُ ٱلْبَطْشَةَ ٱلْكُبْرَىٰٓ إِنَّا مُنتَقِمُونَ","en":"The Day We will strike with the greatest assault, indeed, We will take retribution.","tr":"Yawma nabtishu albatshataalkubra inna muntaqimoon","juz":25,"page":496},{"s":44,"a":17,"key":"44:17","ar":"۞ وَلَقَدْ فَتَنَّا قَبْلَهُمْ قَوْمَ فِرْعَوْنَ وَجَآءَهُمْ رَسُولٌ كَرِيمٌ","en":"And We had already tried before them the people of Pharaoh, and there came to them a noble messenger [i.e., Moses],","tr":"Walaqad fatanna qablahum qawmafirAAawna wajaahum rasoolun kareem","juz":25,"page":496},{"s":44,"a":18,"key":"44:18","ar":"أَنْ أَدُّوٓا۟ إِلَىَّ عِبَادَ ٱللَّهِ ۖ إِنِّى لَكُمْ رَسُولٌ أَمِينٌ","en":"[Saying], \"Render to me the servants of Allāh.1 Indeed, I am to you a trustworthy messenger,\"","tr":"An addoo ilayya AAibada Allahiinnee lakum rasoolun ameen","juz":25,"page":496},{"s":44,"a":19,"key":"44:19","ar":"وَأَن لَّا تَعْلُوا۟ عَلَى ٱللَّهِ ۖ إِنِّىٓ ءَاتِيكُم بِسُلْطَـٰنٍ مُّبِينٍ","en":"And [saying], \"Be not haughty with Allāh. Indeed, I have come to you with clear evidence.","tr":"Waan la taAAloo AAala Allahiinnee ateekum bisultanin mubeen","juz":25,"page":497},{"s":44,"a":20,"key":"44:20","ar":"وَإِنِّى عُذْتُ بِرَبِّى وَرَبِّكُمْ أَن تَرْجُمُونِ","en":"And indeed, I have sought refuge in my Lord and your Lord, lest you stone me.1","tr":"Wa-innee AAuthtu birabbee warabbikuman tarjumoon","juz":25,"page":497},{"s":44,"a":21,"key":"44:21","ar":"وَإِن لَّمْ تُؤْمِنُوا۟ لِى فَٱعْتَزِلُونِ","en":"But if you do not believe me, then leave me alone.\"","tr":"Wa-in lam tu/minoo lee faAAtaziloon","juz":25,"page":497},{"s":44,"a":22,"key":"44:22","ar":"فَدَعَا رَبَّهُۥٓ أَنَّ هَـٰٓؤُلَآءِ قَوْمٌ مُّجْرِمُونَ","en":"And [finally] he called to his Lord that these were a criminal people.","tr":"FadaAAa rabbahu anna haola-iqawmun mujrimoon","juz":25,"page":497},{"s":44,"a":23,"key":"44:23","ar":"فَأَسْرِ بِعِبَادِى لَيْلًا إِنَّكُم مُّتَّبَعُونَ","en":"[Allāh said], \"Then set out with My servants by night. Indeed, you are to be pursued.","tr":"Faasri biAAibadee laylan innakummuttabaAAoon","juz":25,"page":497},{"s":44,"a":24,"key":"44:24","ar":"وَٱتْرُكِ ٱلْبَحْرَ رَهْوًا ۖ إِنَّهُمْ جُندٌ مُّغْرَقُونَ","en":"And leave the sea in stillness.1 Indeed, they are an army to be drowned.\"","tr":"Watruki albahra rahwaninnahum jundun mughraqoon","juz":25,"page":497},{"s":44,"a":25,"key":"44:25","ar":"كَمْ تَرَكُوا۟ مِن جَنَّـٰتٍ وَعُيُونٍ","en":"How much they left behind of gardens and springs","tr":"Kam tarakoo min jannatin waAAuyoon","juz":25,"page":497},{"s":44,"a":26,"key":"44:26","ar":"وَزُرُوعٍ وَمَقَامٍ كَرِيمٍ","en":"And crops and noble sites","tr":"WazurooAAin wamaqamin kareem","juz":25,"page":497},{"s":44,"a":27,"key":"44:27","ar":"وَنَعْمَةٍ كَانُوا۟ فِيهَا فَـٰكِهِينَ","en":"And comfort wherein they were amused.","tr":"WanaAAmatin kanoo feeha fakiheen","juz":25,"page":497},{"s":44,"a":28,"key":"44:28","ar":"كَذَٰلِكَ ۖ وَأَوْرَثْنَـٰهَا قَوْمًا ءَاخَرِينَ","en":"Thus. And We caused to inherit it another people.","tr":"Kathalika waawrathnahaqawman akhareen","juz":25,"page":497},{"s":44,"a":29,"key":"44:29","ar":"فَمَا بَكَتْ عَلَيْهِمُ ٱلسَّمَآءُ وَٱلْأَرْضُ وَمَا كَانُوا۟ مُنظَرِينَ","en":"And the heaven and earth wept not for them, nor were they reprieved.","tr":"Fama bakat AAalayhimu assamaowal-ardu wama kanoo munthareen","juz":25,"page":497},{"s":44,"a":30,"key":"44:30","ar":"وَلَقَدْ نَجَّيْنَا بَنِىٓ إِسْرَٰٓءِيلَ مِنَ ٱلْعَذَابِ ٱلْمُهِينِ","en":"And We certainly saved the Children of Israel from the humiliating torment -","tr":"Walaqad najjayna banee isra-eelamina alAAathabi almuheen","juz":25,"page":497},{"s":44,"a":31,"key":"44:31","ar":"مِن فِرْعَوْنَ ۚ إِنَّهُۥ كَانَ عَالِيًا مِّنَ ٱلْمُسْرِفِينَ","en":"From Pharaoh. Indeed, he was a haughty one among the transgressors.","tr":"Min firAAawna innahu kana AAaliyanmina almusrifeen","juz":25,"page":497},{"s":44,"a":32,"key":"44:32","ar":"وَلَقَدِ ٱخْتَرْنَـٰهُمْ عَلَىٰ عِلْمٍ عَلَى ٱلْعَـٰلَمِينَ","en":"And We certainly chose them by knowledge over [all] the worlds.","tr":"Walaqadi ikhtarnahum AAalaAAilmin AAala alAAalameen","juz":25,"page":497},{"s":44,"a":33,"key":"44:33","ar":"وَءَاتَيْنَـٰهُم مِّنَ ٱلْـَٔايَـٰتِ مَا فِيهِ بَلَـٰٓؤٌا۟ مُّبِينٌ","en":"And We gave them of signs that in which there was a clear trial.","tr":"Waataynahum mina al-ayatima feehi balaon mubeen","juz":25,"page":497},{"s":44,"a":34,"key":"44:34","ar":"إِنَّ هَـٰٓؤُلَآءِ لَيَقُولُونَ","en":"Indeed, these [disbelievers] are saying,","tr":"Inna haola-i layaqooloon","juz":25,"page":497},{"s":44,"a":35,"key":"44:35","ar":"إِنْ هِىَ إِلَّا مَوْتَتُنَا ٱلْأُولَىٰ وَمَا نَحْنُ بِمُنشَرِينَ","en":"\"There is not but our first death, and we will not be resurrected.","tr":"In hiya illa mawtatuna al-oolawama nahnu bimunshareen","juz":25,"page":497},{"s":44,"a":36,"key":"44:36","ar":"فَأْتُوا۟ بِـَٔابَآئِنَآ إِن كُنتُمْ صَـٰدِقِينَ","en":"Then bring [back] our forefathers, if you should be truthful.\"","tr":"Fa/too bi-aba-ina inkuntum sadiqeen","juz":25,"page":497},{"s":44,"a":37,"key":"44:37","ar":"أَهُمْ خَيْرٌ أَمْ قَوْمُ تُبَّعٍ وَٱلَّذِينَ مِن قَبْلِهِمْ ۚ أَهْلَكْنَـٰهُمْ ۖ إِنَّهُمْ كَانُوا۟ مُجْرِمِينَ","en":"Are they better or the people of Tubbaʿ1 and those before them? We destroyed them, [for] indeed, they were criminals.","tr":"Ahum khayrun am qawmu tubbaAAin wallatheenamin qablihim ahlaknahum innahum kanoo mujrimeen","juz":25,"page":497},{"s":44,"a":38,"key":"44:38","ar":"وَمَا خَلَقْنَا ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا لَـٰعِبِينَ","en":"And We did not create the heavens and earth and that between them in play.","tr":"Wama khalaqna assamawatiwal-arda wama baynahuma laAAibeen","juz":25,"page":497},{"s":44,"a":39,"key":"44:39","ar":"مَا خَلَقْنَـٰهُمَآ إِلَّا بِٱلْحَقِّ وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ","en":"We did not create them except in truth, but most of them do not know.","tr":"Ma khalaqnahuma illabilhaqqi walakinna aktharahum layaAAlamoon","juz":25,"page":497},{"s":44,"a":40,"key":"44:40","ar":"إِنَّ يَوْمَ ٱلْفَصْلِ مِيقَـٰتُهُمْ أَجْمَعِينَ","en":"Indeed, the Day of Judgement is the appointed time for them all -","tr":"Inna yawma alfasli meeqatuhumajmaAAeen","juz":25,"page":498},{"s":44,"a":41,"key":"44:41","ar":"يَوْمَ لَا يُغْنِى مَوْلًى عَن مَّوْلًى شَيْـًٔا وَلَا هُمْ يُنصَرُونَ","en":"The Day when no relation1 will avail a relation at all, nor will they be helped -","tr":"Yawma la yughnee mawlan AAan mawlanshay-an wala hum yunsaroon","juz":25,"page":498},{"s":44,"a":42,"key":"44:42","ar":"إِلَّا مَن رَّحِمَ ٱللَّهُ ۚ إِنَّهُۥ هُوَ ٱلْعَزِيزُ ٱلرَّحِيمُ","en":"Except those [believers] on whom Allāh has mercy. Indeed, He is the Exalted in Might, the Merciful.","tr":"Illa man rahima Allahuinnahu huwa alAAazeezu arraheem","juz":25,"page":498},{"s":44,"a":43,"key":"44:43","ar":"إِنَّ شَجَرَتَ ٱلزَّقُّومِ","en":"Indeed, the tree of zaqqūm","tr":"Inna shajarata azzaqqoom","juz":25,"page":498},{"s":44,"a":44,"key":"44:44","ar":"طَعَامُ ٱلْأَثِيمِ","en":"Is food for the sinful.","tr":"TaAAamu al-atheem","juz":25,"page":498},{"s":44,"a":45,"key":"44:45","ar":"كَٱلْمُهْلِ يَغْلِى فِى ٱلْبُطُونِ","en":"Like murky oil, it boils within bellies","tr":"Kalmuhli yaghlee fee albutoon","juz":25,"page":498},{"s":44,"a":46,"key":"44:46","ar":"كَغَلْىِ ٱلْحَمِيمِ","en":"Like the boiling of scalding water.","tr":"Kaghalyi alhameem","juz":25,"page":498},{"s":44,"a":47,"key":"44:47","ar":"خُذُوهُ فَٱعْتِلُوهُ إِلَىٰ سَوَآءِ ٱلْجَحِيمِ","en":"[It will be commanded], \"Seize him and drag him into the midst of the Hellfire,","tr":"Khuthoohu faAAtiloohu ilasawa-i aljaheem","juz":25,"page":498},{"s":44,"a":48,"key":"44:48","ar":"ثُمَّ صُبُّوا۟ فَوْقَ رَأْسِهِۦ مِنْ عَذَابِ ٱلْحَمِيمِ","en":"Then pour over his head from the torment of scalding water.\"","tr":"Thumma subboo fawqa ra/sihi min AAathabialhameem","juz":25,"page":498},{"s":44,"a":49,"key":"44:49","ar":"ذُقْ إِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْكَرِيمُ","en":"[It will be said], \"Taste! Indeed, you are the honored, the noble!1","tr":"Thuq innaka anta alAAazeezu alkareem","juz":25,"page":498},{"s":44,"a":50,"key":"44:50","ar":"إِنَّ هَـٰذَا مَا كُنتُم بِهِۦ تَمْتَرُونَ","en":"Indeed, this is what you used to dispute.\"","tr":"Inna hatha ma kuntum bihitamtaroon","juz":25,"page":498},{"s":44,"a":51,"key":"44:51","ar":"إِنَّ ٱلْمُتَّقِينَ فِى مَقَامٍ أَمِينٍ","en":"Indeed, the righteous will be in a secure place:","tr":"Inna almuttaqeena fee maqamin ameen","juz":25,"page":498},{"s":44,"a":52,"key":"44:52","ar":"فِى جَنَّـٰتٍ وَعُيُونٍ","en":"Within gardens and springs,","tr":"Fee jannatin waAAuyoon","juz":25,"page":498},{"s":44,"a":53,"key":"44:53","ar":"يَلْبَسُونَ مِن سُندُسٍ وَإِسْتَبْرَقٍ مُّتَقَـٰبِلِينَ","en":"Wearing [garments of] fine silk and brocade, facing each other.","tr":"Yalbasoona min sundusin wa-istabraqin mutaqabileen","juz":25,"page":498},{"s":44,"a":54,"key":"44:54","ar":"كَذَٰلِكَ وَزَوَّجْنَـٰهُم بِحُورٍ عِينٍ","en":"Thus. And We will marry them to fair women with large, [beautiful] eyes.","tr":"Kathalika wazawwajnahum bihoorinAAeen","juz":25,"page":498},{"s":44,"a":55,"key":"44:55","ar":"يَدْعُونَ فِيهَا بِكُلِّ فَـٰكِهَةٍ ءَامِنِينَ","en":"They will call therein for every [kind of] fruit - safe and secure.","tr":"YadAAoona feeha bikulli fakihatinamineen","juz":25,"page":498},{"s":44,"a":56,"key":"44:56","ar":"لَا يَذُوقُونَ فِيهَا ٱلْمَوْتَ إِلَّا ٱلْمَوْتَةَ ٱلْأُولَىٰ ۖ وَوَقَىٰهُمْ عَذَابَ ٱلْجَحِيمِ","en":"They will not taste death therein except the first death, and He will have protected them from the punishment of Hellfire","tr":"La yathooqoona feehaalmawta illa almawtata al-oola wawaqahum AAathabaaljaheem","juz":25,"page":498},{"s":44,"a":57,"key":"44:57","ar":"فَضْلًا مِّن رَّبِّكَ ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"As bounty from your Lord. That is what is the great attainment.","tr":"Fadlan min rabbika thalikahuwa alfawzu alAAatheem","juz":25,"page":498},{"s":44,"a":58,"key":"44:58","ar":"فَإِنَّمَا يَسَّرْنَـٰهُ بِلِسَانِكَ لَعَلَّهُمْ يَتَذَكَّرُونَ","en":"And indeed, We have eased it [i.e., the Qur’ān] in your tongue that they might be reminded.","tr":"Fa-innama yassarnahu bilisanikalaAAallahum yatathakkaroon","juz":25,"page":498},{"s":44,"a":59,"key":"44:59","ar":"فَٱرْتَقِبْ إِنَّهُم مُّرْتَقِبُونَ","en":"So watch, [O Muḥammad]; indeed, they are watching [for your end].","tr":"Fartaqib innahum murtaqiboon","juz":25,"page":498},{"s":45,"a":1,"key":"45:1","ar":" حمٓ","en":"Ḥā, Meem.1","tr":"Ha-meem","juz":25,"page":499},{"s":45,"a":2,"key":"45:2","ar":"تَنزِيلُ ٱلْكِتَـٰبِ مِنَ ٱللَّهِ ٱلْعَزِيزِ ٱلْحَكِيمِ","en":"The revelation of the Book is from Allāh, the Exalted in Might, the Wise.","tr":"Tanzeelu alkitabi mina AllahialAAazeezi alhakeem","juz":25,"page":499},{"s":45,"a":3,"key":"45:3","ar":"إِنَّ فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ لَـَٔايَـٰتٍ لِّلْمُؤْمِنِينَ","en":"Indeed, within the heavens and earth are signs for the believers.","tr":"Inna fee assamawati wal-ardilaayatin lilmu/mineen","juz":25,"page":499},{"s":45,"a":4,"key":"45:4","ar":"وَفِى خَلْقِكُمْ وَمَا يَبُثُّ مِن دَآبَّةٍ ءَايَـٰتٌ لِّقَوْمٍ يُوقِنُونَ","en":"And in the creation of yourselves and what He disperses of moving creatures are signs for people who are certain [in faith].","tr":"Wafee khalqikum wama yabuththu min dabbatinayatun liqawmin yooqinoon","juz":25,"page":499},{"s":45,"a":5,"key":"45:5","ar":"وَٱخْتِلَـٰفِ ٱلَّيْلِ وَٱلنَّهَارِ وَمَآ أَنزَلَ ٱللَّهُ مِنَ ٱلسَّمَآءِ مِن رِّزْقٍ فَأَحْيَا بِهِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا وَتَصْرِيفِ ٱلرِّيَـٰحِ ءَايَـٰتٌ لِّقَوْمٍ يَعْقِلُونَ","en":"And [in] the alternation of night and day and [in] what Allāh sends down from the sky of provision [i.e., rain] and gives life thereby to the earth after its lifelessness and [in His] directing of the winds are signs for a people who reason.","tr":"Wakhtilafi allayli wannahariwama anzala Allahu mina assama-i minrizqin faahya bihi al-arda baAAda mawtihawatasreefi arriyahi ayatunliqawmin yaAAqiloon","juz":25,"page":499},{"s":45,"a":6,"key":"45:6","ar":"تِلْكَ ءَايَـٰتُ ٱللَّهِ نَتْلُوهَا عَلَيْكَ بِٱلْحَقِّ ۖ فَبِأَىِّ حَدِيثٍۭ بَعْدَ ٱللَّهِ وَءَايَـٰتِهِۦ يُؤْمِنُونَ","en":"These are the verses of Allāh which We recite to you in truth. Then in what statement after Allāh and His verses will they believe?","tr":"Tilka ayatu Allahinatlooha AAalayka bilhaqqi fabi-ayyi hadeethinbaAAda Allahi waayatihi yu/minoon","juz":25,"page":499},{"s":45,"a":7,"key":"45:7","ar":"وَيْلٌ لِّكُلِّ أَفَّاكٍ أَثِيمٍ","en":"Woe to every sinful liar","tr":"Waylun likulli affakin atheem","juz":25,"page":499},{"s":45,"a":8,"key":"45:8","ar":"يَسْمَعُ ءَايَـٰتِ ٱللَّهِ تُتْلَىٰ عَلَيْهِ ثُمَّ يُصِرُّ مُسْتَكْبِرًا كَأَن لَّمْ يَسْمَعْهَا ۖ فَبَشِّرْهُ بِعَذَابٍ أَلِيمٍ","en":"Who hears the verses of Allāh recited to him, then persists arrogantly as if he had not heard them. So give him tidings of a painful punishment.","tr":"YasmaAAu ayati Allahitutla AAalayhi thumma yusirru mustakbiran kaan lamyasmaAAha fabashshirhu biAAathabin aleem","juz":25,"page":499},{"s":45,"a":9,"key":"45:9","ar":"وَإِذَا عَلِمَ مِنْ ءَايَـٰتِنَا شَيْـًٔا ٱتَّخَذَهَا هُزُوًا ۚ أُو۟لَـٰٓئِكَ لَهُمْ عَذَابٌ مُّهِينٌ","en":"And when he knows anything of Our verses, he takes them in ridicule. Those will have a humiliating punishment.","tr":"Wa-itha AAalima min ayatinashay-an ittakhathaha huzuwan ola-ika lahumAAathabun muheen","juz":25,"page":499},{"s":45,"a":10,"key":"45:10","ar":"مِّن وَرَآئِهِمْ جَهَنَّمُ ۖ وَلَا يُغْنِى عَنْهُم مَّا كَسَبُوا۟ شَيْـًٔا وَلَا مَا ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ أَوْلِيَآءَ ۖ وَلَهُمْ عَذَابٌ عَظِيمٌ","en":"Before them1 is Hell, and what they had earned will not avail them at all nor what they had taken besides Allāh as allies. And they will have a great punishment.","tr":"Min wara-ihim jahannamu walayughnee AAanhum ma kasaboo shay-an wala maittakhathoo min dooni Allahi awliyaa walahumAAathabun AAatheem","juz":25,"page":499},{"s":45,"a":11,"key":"45:11","ar":"هَـٰذَا هُدًى ۖ وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَـٰتِ رَبِّهِمْ لَهُمْ عَذَابٌ مِّن رِّجْزٍ أَلِيمٌ","en":"This [Qur’ān] is guidance. And those who have disbelieved in the verses of their Lord will have a painful punishment of foul nature.","tr":"Hatha hudan wallatheenakafaroo bi-ayati rabbihim lahum AAathabunmin rijzin aleem","juz":25,"page":499},{"s":45,"a":12,"key":"45:12","ar":"۞ ٱللَّهُ ٱلَّذِى سَخَّرَ لَكُمُ ٱلْبَحْرَ لِتَجْرِىَ ٱلْفُلْكُ فِيهِ بِأَمْرِهِۦ وَلِتَبْتَغُوا۟ مِن فَضْلِهِۦ وَلَعَلَّكُمْ تَشْكُرُونَ","en":"It is Allāh who subjected to you the sea so that ships may sail upon it by His command and that you may seek of His bounty; and perhaps you will be grateful.","tr":"Allahu allathee sakhkharalakumu albahra litajriya alfulku feehi bi-amrihiwalitabtaghoo min fadlihi walaAAallakum tashkuroon","juz":25,"page":499},{"s":45,"a":13,"key":"45:13","ar":"وَسَخَّرَ لَكُم مَّا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ جَمِيعًا مِّنْهُ ۚ إِنَّ فِى ذَٰلِكَ لَـَٔايَـٰتٍ لِّقَوْمٍ يَتَفَكَّرُونَ","en":"And He has subjected to you whatever is in the heavens and whatever is on the earth - all from Him. Indeed in that are signs for a people who give thought.","tr":"Wasakhkhara lakum ma fee assamawatiwama fee al-ardi jameeAAan minhu inna fee thalikalaayatin liqawmin yatafakkaroon","juz":25,"page":499},{"s":45,"a":14,"key":"45:14","ar":"قُل لِّلَّذِينَ ءَامَنُوا۟ يَغْفِرُوا۟ لِلَّذِينَ لَا يَرْجُونَ أَيَّامَ ٱللَّهِ لِيَجْزِىَ قَوْمًۢا بِمَا كَانُوا۟ يَكْسِبُونَ","en":"Say, [O Muḥammad], to those who have believed that they [should] forgive those who expect not the days of Allāh [i.e., of His retribution] so that He may recompense a people1 for what they used to earn.","tr":"Qul lillatheena amanooyaghfiroo lillatheena la yarjoona ayyama Allahiliyajziya qawman bima kanoo yaksiboon","juz":25,"page":500},{"s":45,"a":15,"key":"45:15","ar":"مَنْ عَمِلَ صَـٰلِحًا فَلِنَفْسِهِۦ ۖ وَمَنْ أَسَآءَ فَعَلَيْهَا ۖ ثُمَّ إِلَىٰ رَبِّكُمْ تُرْجَعُونَ","en":"Whoever does a good deed - it is for himself; and whoever does evil - it is against it [i.e., the self or soul]. Then to your Lord you will be returned.","tr":"Man AAamila salihanfalinafsihi waman asaa faAAalayha thumma ilarabbikum turjaAAoon","juz":25,"page":500},{"s":45,"a":16,"key":"45:16","ar":"وَلَقَدْ ءَاتَيْنَا بَنِىٓ إِسْرَٰٓءِيلَ ٱلْكِتَـٰبَ وَٱلْحُكْمَ وَٱلنُّبُوَّةَ وَرَزَقْنَـٰهُم مِّنَ ٱلطَّيِّبَـٰتِ وَفَضَّلْنَـٰهُمْ عَلَى ٱلْعَـٰلَمِينَ","en":"And We did certainly give the Children of Israel the Scripture and judgement1 and prophethood, and We provided them with good things and preferred them over the worlds.","tr":"Walaqad atayna banee isra-eelaalkitaba walhukma wannubuwwatawarazaqnahum mina attayyibati wafaddalnahumAAala alAAalameen","juz":25,"page":500},{"s":45,"a":17,"key":"45:17","ar":"وَءَاتَيْنَـٰهُم بَيِّنَـٰتٍ مِّنَ ٱلْأَمْرِ ۖ فَمَا ٱخْتَلَفُوٓا۟ إِلَّا مِنۢ بَعْدِ مَا جَآءَهُمُ ٱلْعِلْمُ بَغْيًۢا بَيْنَهُمْ ۚ إِنَّ رَبَّكَ يَقْضِى بَيْنَهُمْ يَوْمَ ٱلْقِيَـٰمَةِ فِيمَا كَانُوا۟ فِيهِ يَخْتَلِفُونَ","en":"And We gave them clear proofs of the matter [of religion]. And they did not differ except after knowledge had come to them - out of jealous animosity between themselves. Indeed, your Lord will judge between them on the Day of Resurrection concerning that over which they used to differ.","tr":"Waataynahum bayyinatinmina al-amri fama ikhtalafoo illa min baAAdi majaahumu alAAilmu baghyan baynahum inna rabbaka yaqdeebaynahum yawma alqiyamati feema kanoo feehiyakhtalifoon","juz":25,"page":500},{"s":45,"a":18,"key":"45:18","ar":"ثُمَّ جَعَلْنَـٰكَ عَلَىٰ شَرِيعَةٍ مِّنَ ٱلْأَمْرِ فَٱتَّبِعْهَا وَلَا تَتَّبِعْ أَهْوَآءَ ٱلَّذِينَ لَا يَعْلَمُونَ","en":"Then We put you, [O Muḥammad], on an ordained way concerning the matter [of religion]; so follow it and do not follow the inclinations of those who do not know.","tr":"Thumma jaAAalnaka AAalashareeAAatin mina al-amri fattabiAAha walatattabiAA ahwaa allatheena la yaAAlamoon","juz":25,"page":500},{"s":45,"a":19,"key":"45:19","ar":"إِنَّهُمْ لَن يُغْنُوا۟ عَنكَ مِنَ ٱللَّهِ شَيْـًٔا ۚ وَإِنَّ ٱلظَّـٰلِمِينَ بَعْضُهُمْ أَوْلِيَآءُ بَعْضٍ ۖ وَٱللَّهُ وَلِىُّ ٱلْمُتَّقِينَ","en":"Indeed, they will never avail you against Allāh at all. And indeed, the wrongdoers are allies of one another; but Allāh is the protector of the righteous.","tr":"Innahum lan yughnoo AAanka mina Allahishay-an wa-inna aththalimeena baAAduhumawliyao baAAdin wallahu waliyyualmuttaqeen","juz":25,"page":500},{"s":45,"a":20,"key":"45:20","ar":"هَـٰذَا بَصَـٰٓئِرُ لِلنَّاسِ وَهُدًى وَرَحْمَةٌ لِّقَوْمٍ يُوقِنُونَ","en":"This [Qur’ān] is enlightenment for mankind and guidance and mercy for a people who are certain [in faith].","tr":"Hatha basa-iru linnasiwahudan warahmatun liqawmin yooqinoon","juz":25,"page":500},{"s":45,"a":21,"key":"45:21","ar":"أَمْ حَسِبَ ٱلَّذِينَ ٱجْتَرَحُوا۟ ٱلسَّيِّـَٔاتِ أَن نَّجْعَلَهُمْ كَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ سَوَآءً مَّحْيَاهُمْ وَمَمَاتُهُمْ ۚ سَآءَ مَا يَحْكُمُونَ","en":"Or do those who commit evils think We will make them like those who have believed and done righteous deeds - [make them] equal in their life and their death?1 Evil is that which they judge [i.e., assume].","tr":"Am hasiba allatheena ijtarahooassayyi-ati an najAAalahum kallatheenaamanoo waAAamiloo assalihati sawaanmahyahum wamamatuhum saa ma yahkumoon","juz":25,"page":500},{"s":45,"a":22,"key":"45:22","ar":"وَخَلَقَ ٱللَّهُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ وَلِتُجْزَىٰ كُلُّ نَفْسٍۭ بِمَا كَسَبَتْ وَهُمْ لَا يُظْلَمُونَ","en":"And Allāh created the heavens and earth in truth and so that every soul may be recompensed for what it has earned, and they will not be wronged.","tr":"Wakhalaqa Allahu assamawatiwal-arda bilhaqqi walitujzakullu nafsin bima kasabat wahum la yuthlamoon","juz":25,"page":500},{"s":45,"a":23,"key":"45:23","ar":"أَفَرَءَيْتَ مَنِ ٱتَّخَذَ إِلَـٰهَهُۥ هَوَىٰهُ وَأَضَلَّهُ ٱللَّهُ عَلَىٰ عِلْمٍ وَخَتَمَ عَلَىٰ سَمْعِهِۦ وَقَلْبِهِۦ وَجَعَلَ عَلَىٰ بَصَرِهِۦ غِشَـٰوَةً فَمَن يَهْدِيهِ مِنۢ بَعْدِ ٱللَّهِ ۚ أَفَلَا تَذَكَّرُونَ","en":"Have you seen he who has taken as his god his [own] desire, and Allāh has sent him astray due to knowledge1 and has set a seal upon his hearing and his heart and put over his vision a veil? So who will guide him after Allāh? Then will you not be reminded?","tr":"Afaraayta mani ittakhatha ilahahuhawahu waadallahu Allahu AAalaAAilmin wakhatama AAala samAAihi waqalbihi wajaAAala AAalabasarihi ghishawatan faman yahdeehi min baAAdi Allahiafala tathakkaroon","juz":25,"page":501},{"s":45,"a":24,"key":"45:24","ar":"وَقَالُوا۟ مَا هِىَ إِلَّا حَيَاتُنَا ٱلدُّنْيَا نَمُوتُ وَنَحْيَا وَمَا يُهْلِكُنَآ إِلَّا ٱلدَّهْرُ ۚ وَمَا لَهُم بِذَٰلِكَ مِنْ عِلْمٍ ۖ إِنْ هُمْ إِلَّا يَظُنُّونَ","en":"And they say, \"There is not but our worldly life; we die and live,1 and nothing destroys us except time.\" And they have of that no knowledge; they are only assuming.","tr":"Waqaloo ma hiya illa hayatunaaddunya namootu wanahya wamayuhlikuna illa addahru wama lahum bithalikamin AAilmin in hum illa yathunnoon","juz":25,"page":501},{"s":45,"a":25,"key":"45:25","ar":"وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَـٰتُنَا بَيِّنَـٰتٍ مَّا كَانَ حُجَّتَهُمْ إِلَّآ أَن قَالُوا۟ ٱئْتُوا۟ بِـَٔابَآئِنَآ إِن كُنتُمْ صَـٰدِقِينَ","en":"And when Our verses are recited to them as clear evidences, their argument is only that they say, \"Bring [back] our forefathers, if you should be truthful.\"","tr":"Wa-itha tutla AAalayhim ayatunabayyinatin ma kana hujjatahum illaan qaloo i/too bi-aba-ina in kuntum sadiqeen","juz":25,"page":501},{"s":45,"a":26,"key":"45:26","ar":"قُلِ ٱللَّهُ يُحْيِيكُمْ ثُمَّ يُمِيتُكُمْ ثُمَّ يَجْمَعُكُمْ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ لَا رَيْبَ فِيهِ وَلَـٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ","en":"Say, \"Allāh causes you to live, then causes you to die; then He will assemble you for the Day of Resurrection, about which there is no doubt, but most of the people do not know.\"","tr":"Quli Allahu yuhyeekum thummayumeetukum thumma yajmaAAukum ila yawmi alqiyamatila rayba feehi walakinna akthara annasila yaAAlamoon","juz":25,"page":501},{"s":45,"a":27,"key":"45:27","ar":"وَلِلَّهِ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَيَوْمَ تَقُومُ ٱلسَّاعَةُ يَوْمَئِذٍ يَخْسَرُ ٱلْمُبْطِلُونَ","en":"And to Allāh belongs the dominion of the heavens and the earth. And the Day the Hour appears - that Day the falsifiers will lose.","tr":"Walillahi mulku assamawatiwal-ardi wayawma taqoomu assaAAatuyawma-ithin yakhsaru almubtiloon","juz":25,"page":501},{"s":45,"a":28,"key":"45:28","ar":"وَتَرَىٰ كُلَّ أُمَّةٍ جَاثِيَةً ۚ كُلُّ أُمَّةٍ تُدْعَىٰٓ إِلَىٰ كِتَـٰبِهَا ٱلْيَوْمَ تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَ","en":"And you will see every nation kneeling [from fear]. Every nation will be called to its record [and told], \"Today you will be recompensed for what you used to do.","tr":"Watara kulla ommatin jathiyatankullu ommatin tudAAa ila kitabihaalyawma tujzawna ma kuntum taAAmaloon","juz":25,"page":501},{"s":45,"a":29,"key":"45:29","ar":"هَـٰذَا كِتَـٰبُنَا يَنطِقُ عَلَيْكُم بِٱلْحَقِّ ۚ إِنَّا كُنَّا نَسْتَنسِخُ مَا كُنتُمْ تَعْمَلُونَ","en":"This, Our record, speaks about you in truth. Indeed, We were having transcribed1 whatever you used to do.\"","tr":"Hatha kitabuna yantiquAAalaykum bilhaqqi inna kunnanastansikhu ma kuntum taAAmaloon","juz":25,"page":501},{"s":45,"a":30,"key":"45:30","ar":"فَأَمَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ فَيُدْخِلُهُمْ رَبُّهُمْ فِى رَحْمَتِهِۦ ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْمُبِينُ","en":"So as for those who believed and did righteous deeds, their Lord will admit them into His mercy. That is what is the clear attainment.","tr":"Faamma allatheena amanoowaAAamiloo assalihati fayudkhiluhumrabbuhum fee rahmatihi thalika huwa alfawzualmubeen","juz":25,"page":501},{"s":45,"a":31,"key":"45:31","ar":"وَأَمَّا ٱلَّذِينَ كَفَرُوٓا۟ أَفَلَمْ تَكُنْ ءَايَـٰتِى تُتْلَىٰ عَلَيْكُمْ فَٱسْتَكْبَرْتُمْ وَكُنتُمْ قَوْمًا مُّجْرِمِينَ","en":"But as for those who disbelieved, [it will be said], \"Were not Our verses recited to you, but you were arrogant and became a criminal people?","tr":"Waamma allatheena kafarooafalam takun ayatee tutla AAalaykum fastakbartumwakuntum qawman mujrimeen","juz":25,"page":501},{"s":45,"a":32,"key":"45:32","ar":"وَإِذَا قِيلَ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ وَٱلسَّاعَةُ لَا رَيْبَ فِيهَا قُلْتُم مَّا نَدْرِى مَا ٱلسَّاعَةُ إِن نَّظُنُّ إِلَّا ظَنًّا وَمَا نَحْنُ بِمُسْتَيْقِنِينَ","en":"And when it was said, 'Indeed, the promise of Allāh is truth and the Hour [is coming] - no doubt about it,' you said, 'We know not what is the Hour. We assume only assumption, and we are not convinced.'\"","tr":"Wa-itha qeela inna waAAda Allahihaqqun wassaAAatu la rayba feehaqultum ma nadree ma assaAAatu in nathunnuilla thannan wama nahnubimustayqineen","juz":25,"page":501},{"s":45,"a":33,"key":"45:33","ar":"وَبَدَا لَهُمْ سَيِّـَٔاتُ مَا عَمِلُوا۟ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"And the evil consequences of what they did will appear to them, and they will be enveloped by what they used to ridicule.","tr":"Wabada lahum sayyi-atu maAAamiloo wahaqa bihim ma kanoo bihiyastahzi-oon","juz":25,"page":502},{"s":45,"a":34,"key":"45:34","ar":"وَقِيلَ ٱلْيَوْمَ نَنسَىٰكُمْ كَمَا نَسِيتُمْ لِقَآءَ يَوْمِكُمْ هَـٰذَا وَمَأْوَىٰكُمُ ٱلنَّارُ وَمَا لَكُم مِّن نَّـٰصِرِينَ","en":"And it will be said, \"Today We will forget you as you forgot the meeting of this Day of yours, and your refuge is the Fire, and for you there are no helpers.","tr":"Waqeela alyawma nansakum kamanaseetum liqaa yawmikum hatha wama/wakumu annaruwama lakum min nasireen","juz":25,"page":502},{"s":45,"a":35,"key":"45:35","ar":"ذَٰلِكُم بِأَنَّكُمُ ٱتَّخَذْتُمْ ءَايَـٰتِ ٱللَّهِ هُزُوًا وَغَرَّتْكُمُ ٱلْحَيَوٰةُ ٱلدُّنْيَا ۚ فَٱلْيَوْمَ لَا يُخْرَجُونَ مِنْهَا وَلَا هُمْ يُسْتَعْتَبُونَ","en":"That is because you took the verses of Allāh in ridicule, and worldly life deluded you.\" So that Day they will not be removed from it, nor will they be asked to appease [Allāh].","tr":"Thalikum bi-annakumu ittakhathtumayati Allahi huzuwan wagharratkumu alhayatuaddunya falyawma la yukhrajoonaminha wala hum yustaAAtaboon","juz":25,"page":502},{"s":45,"a":36,"key":"45:36","ar":"فَلِلَّهِ ٱلْحَمْدُ رَبِّ ٱلسَّمَـٰوَٰتِ وَرَبِّ ٱلْأَرْضِ رَبِّ ٱلْعَـٰلَمِينَ","en":"Then, to Allāh belongs [all] praise - Lord of the heavens and Lord of the earth, Lord of the worlds.","tr":"Falillahi alhamdu rabbi assamawatiwarabbi al-ardi rabbi alAAalameen","juz":25,"page":502},{"s":45,"a":37,"key":"45:37","ar":"وَلَهُ ٱلْكِبْرِيَآءُ فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"And to Him belongs [all] grandeur within the heavens and the earth, and He is the Exalted in Might, the Wise.","tr":"Walahu alkibriyao fee assamawatiwal-ardi wahuwa alAAazeezu alhakeem","juz":25,"page":502},{"s":46,"a":1,"key":"46:1","ar":" حمٓ","en":"Ḥā, Meem.1","tr":"Ha-meem","juz":26,"page":502},{"s":46,"a":2,"key":"46:2","ar":"تَنزِيلُ ٱلْكِتَـٰبِ مِنَ ٱللَّهِ ٱلْعَزِيزِ ٱلْحَكِيمِ","en":"The revelation of the Book is from Allāh, the Exalted in Might, the Wise.","tr":"Tanzeelu alkitabi mina AllahialAAazeezi alhakeem","juz":26,"page":502},{"s":46,"a":3,"key":"46:3","ar":"مَا خَلَقْنَا ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَآ إِلَّا بِٱلْحَقِّ وَأَجَلٍ مُّسَمًّى ۚ وَٱلَّذِينَ كَفَرُوا۟ عَمَّآ أُنذِرُوا۟ مُعْرِضُونَ","en":"We did not create the heavens and earth and what is between them except in truth and [for] a specified term. But those who disbelieve, from that of which they are warned, are turning away.","tr":"Ma khalaqna assamawatiwal-arda wama baynahuma illabilhaqqi waajalin musamman wallatheenakafaroo AAamma onthiroo muAAridoon","juz":26,"page":502},{"s":46,"a":4,"key":"46:4","ar":"قُلْ أَرَءَيْتُم مَّا تَدْعُونَ مِن دُونِ ٱللَّهِ أَرُونِى مَاذَا خَلَقُوا۟ مِنَ ٱلْأَرْضِ أَمْ لَهُمْ شِرْكٌ فِى ٱلسَّمَـٰوَٰتِ ۖ ٱئْتُونِى بِكِتَـٰبٍ مِّن قَبْلِ هَـٰذَآ أَوْ أَثَـٰرَةٍ مِّنْ عِلْمٍ إِن كُنتُمْ صَـٰدِقِينَ","en":"Say, [O Muḥammad], \"Have you considered that which you invoke besides Allāh? Show me what they have created of the earth; or did they have partnership in [creation of] the heavens? Bring me a scripture [revealed] before this or a [remaining] trace of knowledge, if you should be truthful.\"","tr":"Qul araaytum ma tadAAoona min dooniAllahi aroonee matha khalaqoo mina al-ardiam lahum shirkun fee assamawati eetooneebikitabin min qabli hatha aw atharatin minAAilmin in kuntum sadiqeen","juz":26,"page":502},{"s":46,"a":5,"key":"46:5","ar":"وَمَنْ أَضَلُّ مِمَّن يَدْعُوا۟ مِن دُونِ ٱللَّهِ مَن لَّا يَسْتَجِيبُ لَهُۥٓ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ وَهُمْ عَن دُعَآئِهِمْ غَـٰفِلُونَ","en":"And who is more astray than he who invokes besides Allāh those who will not respond to him until the Day of Resurrection [i.e., never], and they, of their invocation, are unaware.","tr":"Waman adallu mimman yadAAoo min dooniAllahi man la yastajeebu lahu ila yawmialqiyamati wahum AAan duAAa-ihim ghafiloon","juz":26,"page":502},{"s":46,"a":6,"key":"46:6","ar":"وَإِذَا حُشِرَ ٱلنَّاسُ كَانُوا۟ لَهُمْ أَعْدَآءً وَكَانُوا۟ بِعِبَادَتِهِمْ كَـٰفِرِينَ","en":"And when the people are gathered [that Day], they [who were invoked] will be enemies to them, and they will be deniers of their worship.","tr":"Wa-itha hushira annasukanoo lahum aAAdaan wakanoo biAAibadatihimkafireen","juz":26,"page":503},{"s":46,"a":7,"key":"46:7","ar":"وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَـٰتُنَا بَيِّنَـٰتٍ قَالَ ٱلَّذِينَ كَفَرُوا۟ لِلْحَقِّ لَمَّا جَآءَهُمْ هَـٰذَا سِحْرٌ مُّبِينٌ","en":"And when Our verses are recited to them as clear evidences, those who disbelieve say of the truth when it has come to them, \"This is obvious magic.\"","tr":"Wa-itha tutla AAalayhim ayatunabayyinatin qala allatheena kafaroo lilhaqqilamma jaahum hatha sihrun mubeen","juz":26,"page":503},{"s":46,"a":8,"key":"46:8","ar":"أَمْ يَقُولُونَ ٱفْتَرَىٰهُ ۖ قُلْ إِنِ ٱفْتَرَيْتُهُۥ فَلَا تَمْلِكُونَ لِى مِنَ ٱللَّهِ شَيْـًٔا ۖ هُوَ أَعْلَمُ بِمَا تُفِيضُونَ فِيهِ ۖ كَفَىٰ بِهِۦ شَهِيدًۢا بَيْنِى وَبَيْنَكُمْ ۖ وَهُوَ ٱلْغَفُورُ ٱلرَّحِيمُ","en":"Or do they say, \"He has invented it\"? Say, \"If I have invented it, you will not possess for me [the power of protection] from Allāh at all. He is most knowing of that in which you are involved.1 Sufficient is He as Witness between me and you, and He is the Forgiving, the Merciful.\"","tr":"Am yaqooloona iftarahu qul iniiftaraytuhu fala tamlikoona lee mina Allahi shay-anhuwa aAAlamu bima tufeedoona feehi kafa bihishaheedan baynee wabaynakum wahuwa alghafooru arraheem","juz":26,"page":503},{"s":46,"a":9,"key":"46:9","ar":"قُلْ مَا كُنتُ بِدْعًا مِّنَ ٱلرُّسُلِ وَمَآ أَدْرِى مَا يُفْعَلُ بِى وَلَا بِكُمْ ۖ إِنْ أَتَّبِعُ إِلَّا مَا يُوحَىٰٓ إِلَىَّ وَمَآ أَنَا۠ إِلَّا نَذِيرٌ مُّبِينٌ","en":"Say, \"I am not something original among the messengers,1 nor do I know what will be done with me or with you. I only follow that which is revealed to me, and I am not but a clear warner.\"","tr":"Qul ma kuntu bidAAan mina arrusuliwama adree ma yufAAalu bee wala bikum inattabiAAu illa ma yooha ilayya wamaana illa natheerun mubeen","juz":26,"page":503},{"s":46,"a":10,"key":"46:10","ar":"قُلْ أَرَءَيْتُمْ إِن كَانَ مِنْ عِندِ ٱللَّهِ وَكَفَرْتُم بِهِۦ وَشَهِدَ شَاهِدٌ مِّنۢ بَنِىٓ إِسْرَٰٓءِيلَ عَلَىٰ مِثْلِهِۦ فَـَٔامَنَ وَٱسْتَكْبَرْتُمْ ۖ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"Say, \"Have you considered: if it [i.e., the Qur’ān] was from Allāh, and you disbelieved in it while a witness from the Children of Israel has testified to something similar1 and believed while you were arrogant...?\"2 Indeed, Allāh does not guide the wrongdoing people.","tr":"Qul araaytum in kana min AAindi Allahiwakafartum bihi washahida shahidun min banee isra-eelaAAala mithlihi faamana wastakbartum innaAllaha la yahdee alqawma aththalimeen","juz":26,"page":503},{"s":46,"a":11,"key":"46:11","ar":"وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِلَّذِينَ ءَامَنُوا۟ لَوْ كَانَ خَيْرًا مَّا سَبَقُونَآ إِلَيْهِ ۚ وَإِذْ لَمْ يَهْتَدُوا۟ بِهِۦ فَسَيَقُولُونَ هَـٰذَآ إِفْكٌ قَدِيمٌ","en":"And those who disbelieve say of those who believe, \"If it had [truly] been good, they would not have preceded us to it.\" And when they are not guided by it, they will say, \"This is an ancient falsehood.\"","tr":"Waqala allatheena kafaroolillatheena amanoo law kana khayran masabaqoona ilayhi wa-ith lam yahtadoo bihifasayaqooloona hatha ifkun qadeem","juz":26,"page":503},{"s":46,"a":12,"key":"46:12","ar":"وَمِن قَبْلِهِۦ كِتَـٰبُ مُوسَىٰٓ إِمَامًا وَرَحْمَةً ۚ وَهَـٰذَا كِتَـٰبٌ مُّصَدِّقٌ لِّسَانًا عَرَبِيًّا لِّيُنذِرَ ٱلَّذِينَ ظَلَمُوا۟ وَبُشْرَىٰ لِلْمُحْسِنِينَ","en":"And before it was the scripture of Moses to lead and as a mercy. And this is a confirming Book in an Arabic tongue to warn those who have wronged and as good tidings to the doers of good.","tr":"Wamin qablihi kitabu moosa imamanwarahmatan wahatha kitabun musaddiqunlisanan AAarabiyyan liyunthira allatheena thalamoowabushra lilmuhsineen","juz":26,"page":503},{"s":46,"a":13,"key":"46:13","ar":"إِنَّ ٱلَّذِينَ قَالُوا۟ رَبُّنَا ٱللَّهُ ثُمَّ ٱسْتَقَـٰمُوا۟ فَلَا خَوْفٌ عَلَيْهِمْ وَلَا هُمْ يَحْزَنُونَ","en":"Indeed, those who have said, \"Our Lord is Allāh,\" and then remained on a right course - there will be no fear concerning them, nor will they grieve.","tr":"Inna allatheena qaloo rabbunaAllahu thumma istaqamoo fala khawfunAAalayhim wala hum yahzanoon","juz":26,"page":503},{"s":46,"a":14,"key":"46:14","ar":"أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْجَنَّةِ خَـٰلِدِينَ فِيهَا جَزَآءًۢ بِمَا كَانُوا۟ يَعْمَلُونَ","en":"Those are the companions of Paradise, abiding eternally therein as reward for what they used to do.","tr":"Ola-ika as-habualjannati khalideena feeha jazaan bimakanoo yaAAmaloon","juz":26,"page":503},{"s":46,"a":15,"key":"46:15","ar":"وَوَصَّيْنَا ٱلْإِنسَـٰنَ بِوَٰلِدَيْهِ إِحْسَـٰنًا ۖ حَمَلَتْهُ أُمُّهُۥ كُرْهًا وَوَضَعَتْهُ كُرْهًا ۖ وَحَمْلُهُۥ وَفِصَـٰلُهُۥ ثَلَـٰثُونَ شَهْرًا ۚ حَتَّىٰٓ إِذَا بَلَغَ أَشُدَّهُۥ وَبَلَغَ أَرْبَعِينَ سَنَةً قَالَ رَبِّ أَوْزِعْنِىٓ أَنْ أَشْكُرَ نِعْمَتَكَ ٱلَّتِىٓ أَنْعَمْتَ عَلَىَّ وَعَلَىٰ وَٰلِدَىَّ وَأَنْ أَعْمَلَ صَـٰلِحًا تَرْضَىٰهُ وَأَصْلِحْ لِى فِى ذُرِّيَّتِىٓ ۖ إِنِّى تُبْتُ إِلَيْكَ وَإِنِّى مِنَ ٱلْمُسْلِمِينَ","en":"And We have enjoined upon man, to his parents, good treatment. His mother carried him with hardship and gave birth to him with hardship, and his gestation and weaning [period] is thirty months. [He grows] until, when he reaches maturity and reaches [the age of] forty years, he says, \"My Lord, enable me1 to be grateful for Your favor which You have bestowed upon me and upon my parents and to work righteousness of which You will approve and make righteous for me my offspring. Indeed, I have repented to You, and indeed, I am of the Muslims.\"","tr":"Wawassayna al-insanabiwalidayhi ihsanan hamalat-hu ommuhukurhan wawadaAAat-hu kurhan wahamluhu wafisaluhuthalathoona shahran hatta ithabalagha ashuddahu wabalagha arbaAAeena sanatan qala rabbiawziAAnee an ashkura niAAmataka allatee anAAamta AAalayya waAAalawalidayya waan aAAmala salihan tardahuwaaslih lee fee thurriyyatee innee tubtuilayka wa-innee mina almuslimeen","juz":26,"page":504},{"s":46,"a":16,"key":"46:16","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ نَتَقَبَّلُ عَنْهُمْ أَحْسَنَ مَا عَمِلُوا۟ وَنَتَجَاوَزُ عَن سَيِّـَٔاتِهِمْ فِىٓ أَصْحَـٰبِ ٱلْجَنَّةِ ۖ وَعْدَ ٱلصِّدْقِ ٱلَّذِى كَانُوا۟ يُوعَدُونَ","en":"Those are the ones from whom We will accept the best of what they did and overlook their misdeeds, [their being] among the companions of Paradise. [That is] the promise of truth which they had been promised.","tr":"Ola-ika allatheena nataqabbaluAAanhum ahsana ma AAamiloo wanatajawazu AAansayyi-atihim fee as-habi aljannati waAAda assidqiallathee kanoo yooAAadoon","juz":26,"page":504},{"s":46,"a":17,"key":"46:17","ar":"وَٱلَّذِى قَالَ لِوَٰلِدَيْهِ أُفٍّ لَّكُمَآ أَتَعِدَانِنِىٓ أَنْ أُخْرَجَ وَقَدْ خَلَتِ ٱلْقُرُونُ مِن قَبْلِى وَهُمَا يَسْتَغِيثَانِ ٱللَّهَ وَيْلَكَ ءَامِنْ إِنَّ وَعْدَ ٱللَّهِ حَقٌّ فَيَقُولُ مَا هَـٰذَآ إِلَّآ أَسَـٰطِيرُ ٱلْأَوَّلِينَ","en":"But one who says to his parents, \"Uff1 to you; do you promise me that I will be brought forth [from the earth] when generations before me have already passed on [into oblivion]?\" while they call to Allāh for help [and to their son], \"Woe to you! Believe! Indeed, the promise of Allāh is truth.\" But he says, \"This is not but legends of the former peoples\" -","tr":"Wallathee qala liwalidayhioffin lakuma ataAAidaninee an okhraja waqad khalatialquroonu min qablee wahuma yastagheethani Allahawaylaka amin inna waAAda Allahi haqqunfayaqoolu ma hatha illa asateerual-awwaleen","juz":26,"page":504},{"s":46,"a":18,"key":"46:18","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ حَقَّ عَلَيْهِمُ ٱلْقَوْلُ فِىٓ أُمَمٍ قَدْ خَلَتْ مِن قَبْلِهِم مِّنَ ٱلْجِنِّ وَٱلْإِنسِ ۖ إِنَّهُمْ كَانُوا۟ خَـٰسِرِينَ","en":"Those are the ones upon whom the word [i.e., decree] has come into effect, [who will be] among nations which had passed on before them of jinn and men. Indeed, they [all] were losers.","tr":"Ola-ika allatheena haqqaAAalayhimu alqawlu fee umamin qad khalat min qablihim minaaljinni wal-insi innahum kanoo khasireen","juz":26,"page":504},{"s":46,"a":19,"key":"46:19","ar":"وَلِكُلٍّ دَرَجَـٰتٌ مِّمَّا عَمِلُوا۟ ۖ وَلِيُوَفِّيَهُمْ أَعْمَـٰلَهُمْ وَهُمْ لَا يُظْلَمُونَ","en":"And for all there are degrees [of reward and punishment] for what they have done, and [it is] so that He may fully compensate them for their deeds, and they will not be wronged.","tr":"Walikullin darajatun mimmaAAamiloo waliyuwaffiyahum aAAmalahum wahum la yuthlamoon","juz":26,"page":504},{"s":46,"a":20,"key":"46:20","ar":"وَيَوْمَ يُعْرَضُ ٱلَّذِينَ كَفَرُوا۟ عَلَى ٱلنَّارِ أَذْهَبْتُمْ طَيِّبَـٰتِكُمْ فِى حَيَاتِكُمُ ٱلدُّنْيَا وَٱسْتَمْتَعْتُم بِهَا فَٱلْيَوْمَ تُجْزَوْنَ عَذَابَ ٱلْهُونِ بِمَا كُنتُمْ تَسْتَكْبِرُونَ فِى ٱلْأَرْضِ بِغَيْرِ ٱلْحَقِّ وَبِمَا كُنتُمْ تَفْسُقُونَ","en":"And the Day those who disbelieved are exposed to the Fire [it will be said], \"You exhausted your pleasures during your worldly life and enjoyed them, so this Day you will be awarded the punishment of [extreme] humiliation because you were arrogant upon the earth without right and because you were defiantly disobedient.\"","tr":"Wayawma yuAAradu allatheenakafaroo AAala annari athhabtum tayyibatikumfee hayatikumu addunya wastamtaAAtumbiha falyawma tujzawna AAathaba alhooni bimakuntum tastakbiroona fee al-ardi bighayri alhaqqiwabima kuntum tafsuqoon","juz":26,"page":504},{"s":46,"a":21,"key":"46:21","ar":"۞ وَٱذْكُرْ أَخَا عَادٍ إِذْ أَنذَرَ قَوْمَهُۥ بِٱلْأَحْقَافِ وَقَدْ خَلَتِ ٱلنُّذُرُ مِنۢ بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهِۦٓ أَلَّا تَعْبُدُوٓا۟ إِلَّا ٱللَّهَ إِنِّىٓ أَخَافُ عَلَيْكُمْ عَذَابَ يَوْمٍ عَظِيمٍ","en":"And mention, [O Muḥammad], the brother of ʿAad,1 when he warned his people in [the region of] al-Aḥqāf - and warners had already passed on before him and after him - [saying], \"Do not worship except Allāh. Indeed, I fear for you the punishment of a terrible day.\"2","tr":"Wathkur akha AAadinith anthara qawmahu bil-ahqafiwaqad khalati annuthuru min bayni yadayhi waminkhalfihi alla taAAbudoo illa Allaha inneeakhafu AAalaykum AAathaba yawmin AAatheem","juz":26,"page":505},{"s":46,"a":22,"key":"46:22","ar":"قَالُوٓا۟ أَجِئْتَنَا لِتَأْفِكَنَا عَنْ ءَالِهَتِنَا فَأْتِنَا بِمَا تَعِدُنَآ إِن كُنتَ مِنَ ٱلصَّـٰدِقِينَ","en":"They said, \"Have you come to delude us away from our gods? Then bring us what you promise us, if you should be of the truthful.\"","tr":"Qaloo aji/tana lita/fikanaAAan alihatina fa/tina bima taAAidunain kunta mina assadiqeen","juz":26,"page":505},{"s":46,"a":23,"key":"46:23","ar":"قَالَ إِنَّمَا ٱلْعِلْمُ عِندَ ٱللَّهِ وَأُبَلِّغُكُم مَّآ أُرْسِلْتُ بِهِۦ وَلَـٰكِنِّىٓ أَرَىٰكُمْ قَوْمًا تَجْهَلُونَ","en":"He said, \"Knowledge [of its time] is only with Allāh, and I convey to you that with which I was sent; but I see you [to be] a people behaving ignorantly.\"","tr":"Qala innama alAAilmu AAindaAllahi waoballighukum ma orsiltu bihi walakinneearakum qawman tajhaloon","juz":26,"page":505},{"s":46,"a":24,"key":"46:24","ar":"فَلَمَّا رَأَوْهُ عَارِضًا مُّسْتَقْبِلَ أَوْدِيَتِهِمْ قَالُوا۟ هَـٰذَا عَارِضٌ مُّمْطِرُنَا ۚ بَلْ هُوَ مَا ٱسْتَعْجَلْتُم بِهِۦ ۖ رِيحٌ فِيهَا عَذَابٌ أَلِيمٌ","en":"And when they saw it as a cloud approaching their valleys, they said, \"This is a cloud bringing us rain!\" Rather, it is that for which you were impatient:1 a wind, within it a painful punishment,","tr":"Falamma raawhu AAaridanmustaqbila awdiyatihim qaloo hatha AAaridunmumtiruna bal huwa ma istaAAjaltum bihi reehunfeeha AAathabun aleem","juz":26,"page":505},{"s":46,"a":25,"key":"46:25","ar":"تُدَمِّرُ كُلَّ شَىْءٍۭ بِأَمْرِ رَبِّهَا فَأَصْبَحُوا۟ لَا يُرَىٰٓ إِلَّا مَسَـٰكِنُهُمْ ۚ كَذَٰلِكَ نَجْزِى ٱلْقَوْمَ ٱلْمُجْرِمِينَ","en":"Destroying everything by command of its Lord. And they became so that nothing was seen [of them] except their dwellings. Thus do We recompense the criminal people.","tr":"Tudammiru kulla shay-in bi-amri rabbihafaasbahoo la yura illa masakinuhumkathalika najzee alqawma almujrimeen","juz":26,"page":505},{"s":46,"a":26,"key":"46:26","ar":"وَلَقَدْ مَكَّنَّـٰهُمْ فِيمَآ إِن مَّكَّنَّـٰكُمْ فِيهِ وَجَعَلْنَا لَهُمْ سَمْعًا وَأَبْصَـٰرًا وَأَفْـِٔدَةً فَمَآ أَغْنَىٰ عَنْهُمْ سَمْعُهُمْ وَلَآ أَبْصَـٰرُهُمْ وَلَآ أَفْـِٔدَتُهُم مِّن شَىْءٍ إِذْ كَانُوا۟ يَجْحَدُونَ بِـَٔايَـٰتِ ٱللَّهِ وَحَاقَ بِهِم مَّا كَانُوا۟ بِهِۦ يَسْتَهْزِءُونَ","en":"And We had certainly established them in such as We have not established you, and We made for them hearing and vision and hearts [i.e., intellect]. But their hearing and vision and hearts availed them not from anything [of the punishment] when they were [continually] rejecting the signs of Allāh; and they were enveloped by what they used to ridicule.","tr":"Walaqad makkannahum feema inmakkannakum feehi wajaAAalna lahum samAAan waabsaranwaaf-idatan fama aghna AAanhum samAAuhum walaabsaruhum wala af-idatuhum min shay-in ith kanooyajhadoona bi-ayati Allahi wahaqabihim ma kanoo bihi yastahzi-oon","juz":26,"page":505},{"s":46,"a":27,"key":"46:27","ar":"وَلَقَدْ أَهْلَكْنَا مَا حَوْلَكُم مِّنَ ٱلْقُرَىٰ وَصَرَّفْنَا ٱلْـَٔايَـٰتِ لَعَلَّهُمْ يَرْجِعُونَ","en":"And We have already destroyed what surrounds you of [those] cities, and We have diversified the signs [or verses] that perhaps they might return [from disbelief].","tr":"Walaqad ahlakna ma hawlakummina alqura wasarrafna al-ayatilaAAallahum yarjiAAoon","juz":26,"page":505},{"s":46,"a":28,"key":"46:28","ar":"فَلَوْلَا نَصَرَهُمُ ٱلَّذِينَ ٱتَّخَذُوا۟ مِن دُونِ ٱللَّهِ قُرْبَانًا ءَالِهَةًۢ ۖ بَلْ ضَلُّوا۟ عَنْهُمْ ۚ وَذَٰلِكَ إِفْكُهُمْ وَمَا كَانُوا۟ يَفْتَرُونَ","en":"Then why did those they took besides Allāh as deities by which to approach [Him]1 not aid them? But they had strayed [i.e., departed] from them. And that was their falsehood and what they were inventing.","tr":"Falawla nasarahumu allatheenaittakhathoo min dooni Allahi qurbanan alihatanbal dalloo AAanhum wathalika ifkuhum wama kanooyaftaroon","juz":26,"page":505},{"s":46,"a":29,"key":"46:29","ar":"وَإِذْ صَرَفْنَآ إِلَيْكَ نَفَرًا مِّنَ ٱلْجِنِّ يَسْتَمِعُونَ ٱلْقُرْءَانَ فَلَمَّا حَضَرُوهُ قَالُوٓا۟ أَنصِتُوا۟ ۖ فَلَمَّا قُضِىَ وَلَّوْا۟ إِلَىٰ قَوْمِهِم مُّنذِرِينَ","en":"And [mention, O Muḥammad], when We directed to you a few of the jinn, listening to the Qur’ān. And when they attended it, they said, \"Listen attentively.\" And when it was concluded, they went back to their people as warners.","tr":"Wa-ith sarafna ilaykanafaran mina aljinni yastamiAAoona alqur-ana falammahadaroohu qaloo ansitoo falammaqudiya wallaw ila qawmihim munthireen","juz":26,"page":506},{"s":46,"a":30,"key":"46:30","ar":"قَالُوا۟ يَـٰقَوْمَنَآ إِنَّا سَمِعْنَا كِتَـٰبًا أُنزِلَ مِنۢ بَعْدِ مُوسَىٰ مُصَدِّقًا لِّمَا بَيْنَ يَدَيْهِ يَهْدِىٓ إِلَى ٱلْحَقِّ وَإِلَىٰ طَرِيقٍ مُّسْتَقِيمٍ","en":"They said, \"O our people, indeed we have heard a [recited] Book revealed after Moses confirming what was before it which guides to the truth and to a straight path.","tr":"Qaloo ya qawmana innasamiAAna kitaban onzila min baAAdi moosa musaddiqanlima bayna yadayhi yahdee ila alhaqqi wa-ilatareeqin mustaqeem","juz":26,"page":506},{"s":46,"a":31,"key":"46:31","ar":"يَـٰقَوْمَنَآ أَجِيبُوا۟ دَاعِىَ ٱللَّهِ وَءَامِنُوا۟ بِهِۦ يَغْفِرْ لَكُم مِّن ذُنُوبِكُمْ وَيُجِرْكُم مِّنْ عَذَابٍ أَلِيمٍ","en":"O our people, respond to the Caller [i.e., Messenger] of Allāh1 and believe in him; He [i.e., Allāh] will forgive for you your sins and protect you from a painful punishment.","tr":"Ya qawmana ajeeboo daAAiyaAllahi waaminoo bihi yaghfir lakum min thunoobikumwayujirkum min AAathabin aleem","juz":26,"page":506},{"s":46,"a":32,"key":"46:32","ar":"وَمَن لَّا يُجِبْ دَاعِىَ ٱللَّهِ فَلَيْسَ بِمُعْجِزٍ فِى ٱلْأَرْضِ وَلَيْسَ لَهُۥ مِن دُونِهِۦٓ أَوْلِيَآءُ ۚ أُو۟لَـٰٓئِكَ فِى ضَلَـٰلٍ مُّبِينٍ","en":"But he who does not respond to the Caller of Allāh will not cause failure [to Him] upon earth, and he will not have besides Him any protectors. Those are in manifest error.\"","tr":"Waman la yujib daAAiya Allahifalaysa bimuAAjizin fee al-ardi walaysa lahu min doonihiawliyaa ola-ika fee dalalin mubeen","juz":26,"page":506},{"s":46,"a":33,"key":"46:33","ar":"أَوَلَمْ يَرَوْا۟ أَنَّ ٱللَّهَ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَلَمْ يَعْىَ بِخَلْقِهِنَّ بِقَـٰدِرٍ عَلَىٰٓ أَن يُحْـِۧىَ ٱلْمَوْتَىٰ ۚ بَلَىٰٓ إِنَّهُۥ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Do they not see that Allāh, who created the heavens and earth and did not fail in their creation, is able to give life to the dead? Yes. Indeed, He is over all things competent.","tr":"Awa lam yaraw anna Allaha allatheekhalaqa assamawati wal-ardawalam yaAAya bikhalqihinna biqadirin AAala an yuhyiyaalmawta bala innahu AAala kulli shay-inqadeer","juz":26,"page":506},{"s":46,"a":34,"key":"46:34","ar":"وَيَوْمَ يُعْرَضُ ٱلَّذِينَ كَفَرُوا۟ عَلَى ٱلنَّارِ أَلَيْسَ هَـٰذَا بِٱلْحَقِّ ۖ قَالُوا۟ بَلَىٰ وَرَبِّنَا ۚ قَالَ فَذُوقُوا۟ ٱلْعَذَابَ بِمَا كُنتُمْ تَكْفُرُونَ","en":"And the Day those who disbelieved are exposed to the Fire [it will be said], \"Is this not the truth?\" They will say, \"Yes, by our Lord.\" He will say, \"Then taste the punishment for what you used to deny.\"1","tr":"Wayawma yuAAradu allatheenakafaroo AAala annari alaysa hatha bilhaqqiqaloo bala warabbina qala fathooqooalAAathaba bima kuntum takfuroon","juz":26,"page":506},{"s":46,"a":35,"key":"46:35","ar":"فَٱصْبِرْ كَمَا صَبَرَ أُو۟لُوا۟ ٱلْعَزْمِ مِنَ ٱلرُّسُلِ وَلَا تَسْتَعْجِل لَّهُمْ ۚ كَأَنَّهُمْ يَوْمَ يَرَوْنَ مَا يُوعَدُونَ لَمْ يَلْبَثُوٓا۟ إِلَّا سَاعَةً مِّن نَّهَارٍۭ ۚ بَلَـٰغٌ ۚ فَهَلْ يُهْلَكُ إِلَّا ٱلْقَوْمُ ٱلْفَـٰسِقُونَ","en":"So be patient, [O Muḥammad], as were those of determination among the messengers and do not be impatient for them.1 It will be - on the Day they see that which they are promised - as though they had not remained [in the world] except an hour of a day. [This is] notification. And will [any] be destroyed except the defiantly disobedient people?","tr":"Fasbir kama sabaraoloo alAAazmi mina arrusuli wala tastaAAjil lahumkaannahum yawma yarawna ma yooAAadoona lam yalbathoo illasaAAatan min naharin balaghun fahal yuhlakuilla alqawmu alfasiqoon","juz":26,"page":506},{"s":47,"a":1,"key":"47:1","ar":" ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ أَضَلَّ أَعْمَـٰلَهُمْ","en":"Those who disbelieve and avert [people] from the way of Allāh - He will waste their deeds.1","tr":"Allatheena kafaroo wasaddooAAan sabeeli Allahi adalla aAAmalahum","juz":26,"page":507},{"s":47,"a":2,"key":"47:2","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ وَءَامَنُوا۟ بِمَا نُزِّلَ عَلَىٰ مُحَمَّدٍ وَهُوَ ٱلْحَقُّ مِن رَّبِّهِمْ ۙ كَفَّرَ عَنْهُمْ سَيِّـَٔاتِهِمْ وَأَصْلَحَ بَالَهُمْ","en":"And those who believe and do righteous deeds and believe in what has been sent down upon Muḥammad - and it is the truth from their Lord - He will remove from them their misdeeds and amend their condition.","tr":"Wallatheena amanoowaAAamiloo assalihati waamanoo bimanuzzila AAala muhammadin wahuwa alhaqqu minrabbihim kaffara AAanhum sayyi-atihim waaslahabalahum","juz":26,"page":507},{"s":47,"a":3,"key":"47:3","ar":"ذَٰلِكَ بِأَنَّ ٱلَّذِينَ كَفَرُوا۟ ٱتَّبَعُوا۟ ٱلْبَـٰطِلَ وَأَنَّ ٱلَّذِينَ ءَامَنُوا۟ ٱتَّبَعُوا۟ ٱلْحَقَّ مِن رَّبِّهِمْ ۚ كَذَٰلِكَ يَضْرِبُ ٱللَّهُ لِلنَّاسِ أَمْثَـٰلَهُمْ","en":"That is because those who disbelieve follow falsehood, and those who believe follow the truth from their Lord. Thus does Allāh present to the people their comparisons.1","tr":"Thalika bi-anna allatheenakafaroo ittabaAAoo albatila waanna allatheena amanooittabaAAoo alhaqqa min rabbihim kathalika yadribuAllahu linnasi amthalahum","juz":26,"page":507},{"s":47,"a":4,"key":"47:4","ar":"فَإِذَا لَقِيتُمُ ٱلَّذِينَ كَفَرُوا۟ فَضَرْبَ ٱلرِّقَابِ حَتَّىٰٓ إِذَآ أَثْخَنتُمُوهُمْ فَشُدُّوا۟ ٱلْوَثَاقَ فَإِمَّا مَنًّۢا بَعْدُ وَإِمَّا فِدَآءً حَتَّىٰ تَضَعَ ٱلْحَرْبُ أَوْزَارَهَا ۚ ذَٰلِكَ وَلَوْ يَشَآءُ ٱللَّهُ لَٱنتَصَرَ مِنْهُمْ وَلَـٰكِن لِّيَبْلُوَا۟ بَعْضَكُم بِبَعْضٍ ۗ وَٱلَّذِينَ قُتِلُوا۟ فِى سَبِيلِ ٱللَّهِ فَلَن يُضِلَّ أَعْمَـٰلَهُمْ","en":"So when you meet those who disbelieve [in battle], strike [their] necks until, when you have inflicted slaughter upon them, then secure [their] bonds,1 and either [confer] favor2 afterwards or ransom [them] until the war lays down its burdens.3 That [is the command]. And if Allāh had willed, He could have taken vengeance upon them [Himself], but [He ordered armed struggle] to test some of you by means of others. And those who are killed in the cause of Allāh - never will He waste their deeds.","tr":"Fa-itha laqeetumu allatheenakafaroo fadarba arriqabi hattaitha athkhantumoohum fashuddoo alwathaqa fa-immamannan baAAdu wa-imma fidaan hatta tadaAAaalharbu awzaraha thalika walaw yashaoAllahu lantasara minhum walakinliyabluwa baAAdakum bibaAAdin wallatheenaqutiloo fee sabeeli Allahi falan yudillaaAAmalahum","juz":26,"page":507},{"s":47,"a":5,"key":"47:5","ar":"سَيَهْدِيهِمْ وَيُصْلِحُ بَالَهُمْ","en":"He will guide them and amend their condition","tr":"sayahdeehim wayuslihu balahum","juz":26,"page":507},{"s":47,"a":6,"key":"47:6","ar":"وَيُدْخِلُهُمُ ٱلْجَنَّةَ عَرَّفَهَا لَهُمْ","en":"And admit them to Paradise, which He has made known to them.","tr":"Wayudkhiluhumu aljannata AAarrafahalahum","juz":26,"page":507},{"s":47,"a":7,"key":"47:7","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن تَنصُرُوا۟ ٱللَّهَ يَنصُرْكُمْ وَيُثَبِّتْ أَقْدَامَكُمْ","en":"O you who have believed, if you support Allāh, He will support you and plant firmly your feet.","tr":"Ya ayyuha allatheena amanooin tansuroo Allaha yansurkum wayuthabbit aqdamakum","juz":26,"page":507},{"s":47,"a":8,"key":"47:8","ar":"وَٱلَّذِينَ كَفَرُوا۟ فَتَعْسًا لَّهُمْ وَأَضَلَّ أَعْمَـٰلَهُمْ","en":"But those who disbelieve - for them is misery, and He will waste their deeds.","tr":"Wallatheena kafaroo fataAAsanlahum waadalla aAAmalahum","juz":26,"page":507},{"s":47,"a":9,"key":"47:9","ar":"ذَٰلِكَ بِأَنَّهُمْ كَرِهُوا۟ مَآ أَنزَلَ ٱللَّهُ فَأَحْبَطَ أَعْمَـٰلَهُمْ","en":"That is because they disliked what Allāh revealed, so He rendered worthless their deeds.","tr":"Thalika bi-annahum karihoo maanzala Allahu faahbata aAAmalahum","juz":26,"page":507},{"s":47,"a":10,"key":"47:10","ar":"۞ أَفَلَمْ يَسِيرُوا۟ فِى ٱلْأَرْضِ فَيَنظُرُوا۟ كَيْفَ كَانَ عَـٰقِبَةُ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ دَمَّرَ ٱللَّهُ عَلَيْهِمْ ۖ وَلِلْكَـٰفِرِينَ أَمْثَـٰلُهَا","en":"Have they not traveled through the land and seen how was the end of those before them? Allāh destroyed [everything] over them,1 and for the disbelievers is something comparable.","tr":"Afalam yaseeroo fee al-ardi fayanthurookayfa kana AAaqibatu allatheena min qablihimdammara Allahu AAalayhim walilkafireena amthaluha","juz":26,"page":507},{"s":47,"a":11,"key":"47:11","ar":"ذَٰلِكَ بِأَنَّ ٱللَّهَ مَوْلَى ٱلَّذِينَ ءَامَنُوا۟ وَأَنَّ ٱلْكَـٰفِرِينَ لَا مَوْلَىٰ لَهُمْ","en":"That is because Allāh is the protector of those who have believed and because the disbelievers have no protector.","tr":"Thalika bi-anna Allaha mawlaallatheena amanoo waanna alkafireena lamawla lahum","juz":26,"page":507},{"s":47,"a":12,"key":"47:12","ar":"إِنَّ ٱللَّهَ يُدْخِلُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ۖ وَٱلَّذِينَ كَفَرُوا۟ يَتَمَتَّعُونَ وَيَأْكُلُونَ كَمَا تَأْكُلُ ٱلْأَنْعَـٰمُ وَٱلنَّارُ مَثْوًى لَّهُمْ","en":"Indeed, Allāh will admit those who have believed and done righteous deeds to gardens beneath which rivers flow, but those who disbelieve enjoy themselves and eat as grazing livestock eat, and the Fire will be a residence for them.","tr":"Inna Allaha yudkhilu allatheenaamanoo waAAamiloo assalihati jannatintajree min tahtiha al-anharu wallatheenakafaroo yatamattaAAoona waya/kuloona kama ta/kulu al-anAAamuwannaru mathwan lahum","juz":26,"page":508},{"s":47,"a":13,"key":"47:13","ar":"وَكَأَيِّن مِّن قَرْيَةٍ هِىَ أَشَدُّ قُوَّةً مِّن قَرْيَتِكَ ٱلَّتِىٓ أَخْرَجَتْكَ أَهْلَكْنَـٰهُمْ فَلَا نَاصِرَ لَهُمْ","en":"And how many a city was stronger than your city [i.e., Makkah] which drove you out? We destroyed them; and there was no helper for them.","tr":"Wakaayyin min qaryatin hiya ashaddu quwwatanmin qaryatika allatee akhrajatka ahlaknahum fala nasiralahum","juz":26,"page":508},{"s":47,"a":14,"key":"47:14","ar":"أَفَمَن كَانَ عَلَىٰ بَيِّنَةٍ مِّن رَّبِّهِۦ كَمَن زُيِّنَ لَهُۥ سُوٓءُ عَمَلِهِۦ وَٱتَّبَعُوٓا۟ أَهْوَآءَهُم","en":"So is he who is on clear evidence from his Lord like him to whom the evil of his work has been made attractive and they follow their [own] desires?","tr":"Afaman kana AAala bayyinatinmin rabbihi kaman zuyyina lahu soo-o AAamalihi wattabaAAooahwaahum","juz":26,"page":508},{"s":47,"a":15,"key":"47:15","ar":"مَّثَلُ ٱلْجَنَّةِ ٱلَّتِى وُعِدَ ٱلْمُتَّقُونَ ۖ فِيهَآ أَنْهَـٰرٌ مِّن مَّآءٍ غَيْرِ ءَاسِنٍ وَأَنْهَـٰرٌ مِّن لَّبَنٍ لَّمْ يَتَغَيَّرْ طَعْمُهُۥ وَأَنْهَـٰرٌ مِّنْ خَمْرٍ لَّذَّةٍ لِّلشَّـٰرِبِينَ وَأَنْهَـٰرٌ مِّنْ عَسَلٍ مُّصَفًّى ۖ وَلَهُمْ فِيهَا مِن كُلِّ ٱلثَّمَرَٰتِ وَمَغْفِرَةٌ مِّن رَّبِّهِمْ ۖ كَمَنْ هُوَ خَـٰلِدٌ فِى ٱلنَّارِ وَسُقُوا۟ مَآءً حَمِيمًا فَقَطَّعَ أَمْعَآءَهُمْ","en":"Is the description of Paradise, which the righteous are promised, wherein are rivers of water unaltered,1 rivers of milk the taste of which never changes, rivers of wine delicious to those who drink, and rivers of purified honey, in which they will have from all [kinds of] fruits and forgiveness from their Lord... [Are its inhabitants] like those who abide eternally in the Fire and are given to drink scalding water that will sever their intestines?","tr":"Mathalu aljannati allatee wuAAidaalmuttaqoona feeha anharun min ma-in ghayri asininwaanharun min labanin lam yataghayyar taAAmuhuwaanharun min khamrin laththatin lishsharibeenawaanharun min AAasalin musaffan walahum feehamin kulli aththamarati wamaghfiratun min rabbihimkaman huwa khalidun fee annari wasuqoo maanhameeman faqattaAAa amAAaahum","juz":26,"page":508},{"s":47,"a":16,"key":"47:16","ar":"وَمِنْهُم مَّن يَسْتَمِعُ إِلَيْكَ حَتَّىٰٓ إِذَا خَرَجُوا۟ مِنْ عِندِكَ قَالُوا۟ لِلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ مَاذَا قَالَ ءَانِفًا ۚ أُو۟لَـٰٓئِكَ ٱلَّذِينَ طَبَعَ ٱللَّهُ عَلَىٰ قُلُوبِهِمْ وَٱتَّبَعُوٓا۟ أَهْوَآءَهُمْ","en":"And among them, [O Muḥammad], are those who listen to you, until when they depart from you, they say to those who were given knowledge,1 \"What has he said just now?\" Those are the ones of whom Allāh has sealed over their hearts and who have followed their [own] desires.","tr":"Waminhum man yastamiAAu ilayka hattaitha kharajoo min AAindika qaloo lillatheenaootoo alAAilma matha qala anifan ola-ikaallatheena tabaAAa Allahu AAalaquloobihim wattabaAAoo ahwaahum","juz":26,"page":508},{"s":47,"a":17,"key":"47:17","ar":"وَٱلَّذِينَ ٱهْتَدَوْا۟ زَادَهُمْ هُدًى وَءَاتَىٰهُمْ تَقْوَىٰهُمْ","en":"And those who are guided - He increases them in guidance and gives them their righteousness.1","tr":"Wallatheena ihtadaw zadahumhudan waatahum taqwahum","juz":26,"page":508},{"s":47,"a":18,"key":"47:18","ar":"فَهَلْ يَنظُرُونَ إِلَّا ٱلسَّاعَةَ أَن تَأْتِيَهُم بَغْتَةً ۖ فَقَدْ جَآءَ أَشْرَاطُهَا ۚ فَأَنَّىٰ لَهُمْ إِذَا جَآءَتْهُمْ ذِكْرَىٰهُمْ","en":"Then do they await except that the Hour should come upon them unexpectedly? But already there have come [some of] its indications. Then how [i.e., what good] to them, when it has come, will be their remembrance?","tr":"Fahal yanthuroona illaassaAAata an ta/tiyahum baghtatan faqad jaaashratuha faanna lahum itha jaat-humthikrahum","juz":26,"page":508},{"s":47,"a":19,"key":"47:19","ar":"فَٱعْلَمْ أَنَّهُۥ لَآ إِلَـٰهَ إِلَّا ٱللَّهُ وَٱسْتَغْفِرْ لِذَنۢبِكَ وَلِلْمُؤْمِنِينَ وَٱلْمُؤْمِنَـٰتِ ۗ وَٱللَّهُ يَعْلَمُ مُتَقَلَّبَكُمْ وَمَثْوَىٰكُمْ","en":"So know, [O Muḥammad], that there is no deity except Allāh and ask forgiveness for your sin1 and for the believing men and believing women. And Allāh knows of your movement and your resting place.","tr":"FaAAlam annahu la ilahailla Allahu wastaghfir lithanbikawalilmu/mineena walmu/minati wallahuyaAAlamu mutaqallabakum wamathwakum","juz":26,"page":508},{"s":47,"a":20,"key":"47:20","ar":"وَيَقُولُ ٱلَّذِينَ ءَامَنُوا۟ لَوْلَا نُزِّلَتْ سُورَةٌ ۖ فَإِذَآ أُنزِلَتْ سُورَةٌ مُّحْكَمَةٌ وَذُكِرَ فِيهَا ٱلْقِتَالُ ۙ رَأَيْتَ ٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌ يَنظُرُونَ إِلَيْكَ نَظَرَ ٱلْمَغْشِىِّ عَلَيْهِ مِنَ ٱلْمَوْتِ ۖ فَأَوْلَىٰ لَهُمْ","en":"Those who believe say, \"Why has a sūrah1 not been sent down?\" But when a precise sūrah is revealed and battle is mentioned therein, you see those in whose hearts is disease [i.e., hypocrisy] looking at you with a look of one overcome by death. And more appropriate for them2 [would have been]","tr":"Wayaqoolu allatheena amanoolawla nuzzilat sooratun fa-itha onzilat sooratun muhkamatunwathukira feeha alqitalu raayta allatheenafee quloobihim maradun yanthuroona ilayka natharaalmaghshiyyi AAalayhi mina almawti faawla lahum","juz":26,"page":509},{"s":47,"a":21,"key":"47:21","ar":"طَاعَةٌ وَقَوْلٌ مَّعْرُوفٌ ۚ فَإِذَا عَزَمَ ٱلْأَمْرُ فَلَوْ صَدَقُوا۟ ٱللَّهَ لَكَانَ خَيْرًا لَّهُمْ","en":"Obedience and good words. And when the matter [of fighting] was determined, if they had been true to Allāh, it would have been better for them.","tr":"TaAAatun waqawlun maAAroofun fa-ithaAAazama al-amru falaw sadaqoo Allaha lakanakhayran lahum","juz":26,"page":509},{"s":47,"a":22,"key":"47:22","ar":"فَهَلْ عَسَيْتُمْ إِن تَوَلَّيْتُمْ أَن تُفْسِدُوا۟ فِى ٱلْأَرْضِ وَتُقَطِّعُوٓا۟ أَرْحَامَكُمْ","en":"So would you perhaps, if you turned away,1 cause corruption on earth and sever your [ties of] relationship?","tr":"Fahal AAasaytum in tawallaytum an tufsidoofee al-ardi watuqattiAAoo arhamakum","juz":26,"page":509},{"s":47,"a":23,"key":"47:23","ar":"أُو۟لَـٰٓئِكَ ٱلَّذِينَ لَعَنَهُمُ ٱللَّهُ فَأَصَمَّهُمْ وَأَعْمَىٰٓ أَبْصَـٰرَهُمْ","en":"Those [who do so] are the ones that Allāh has cursed, so He deafened them and blinded their vision.","tr":"Ola-ika allatheena laAAanahumuAllahu faasammahum waaAAma absarahum","juz":26,"page":509},{"s":47,"a":24,"key":"47:24","ar":"أَفَلَا يَتَدَبَّرُونَ ٱلْقُرْءَانَ أَمْ عَلَىٰ قُلُوبٍ أَقْفَالُهَآ","en":"Then do they not reflect upon the Qur’ān, or are there locks upon [their] hearts?","tr":"Afala yatadabbaroona alqur-anaam AAala quloobin aqfaluha","juz":26,"page":509},{"s":47,"a":25,"key":"47:25","ar":"إِنَّ ٱلَّذِينَ ٱرْتَدُّوا۟ عَلَىٰٓ أَدْبَـٰرِهِم مِّنۢ بَعْدِ مَا تَبَيَّنَ لَهُمُ ٱلْهُدَى ۙ ٱلشَّيْطَـٰنُ سَوَّلَ لَهُمْ وَأَمْلَىٰ لَهُمْ","en":"Indeed, those who reverted back [to disbelief] after guidance had become clear to them - Satan enticed them and prolonged hope for them.","tr":"Inna allatheena irtaddoo AAalaadbarihim min baAAdi ma tabayyana lahumu alhudaashshaytanu sawwala lahum waamla lahum","juz":26,"page":509},{"s":47,"a":26,"key":"47:26","ar":"ذَٰلِكَ بِأَنَّهُمْ قَالُوا۟ لِلَّذِينَ كَرِهُوا۟ مَا نَزَّلَ ٱللَّهُ سَنُطِيعُكُمْ فِى بَعْضِ ٱلْأَمْرِ ۖ وَٱللَّهُ يَعْلَمُ إِسْرَارَهُمْ","en":"That is because they said to those who disliked what Allāh sent down,1 \"We will obey you in part of the matter.\" And Allāh knows what they conceal.","tr":"Thalika bi-annahum qaloo lillatheenakarihoo ma nazzala Allahu sanuteeAAukum feebaAAdi al-amri wallahu yaAAlamu israrahum","juz":26,"page":509},{"s":47,"a":27,"key":"47:27","ar":"فَكَيْفَ إِذَا تَوَفَّتْهُمُ ٱلْمَلَـٰٓئِكَةُ يَضْرِبُونَ وُجُوهَهُمْ وَأَدْبَـٰرَهُمْ","en":"Then how [will it be] when the angels take them in death, striking their faces and their backs?","tr":"Fakayfa itha tawaffat-humu almala-ikatuyadriboona wujoohahum waadbarahum","juz":26,"page":509},{"s":47,"a":28,"key":"47:28","ar":"ذَٰلِكَ بِأَنَّهُمُ ٱتَّبَعُوا۟ مَآ أَسْخَطَ ٱللَّهَ وَكَرِهُوا۟ رِضْوَٰنَهُۥ فَأَحْبَطَ أَعْمَـٰلَهُمْ","en":"That is because they followed what angered Allāh and disliked [what earns] His pleasure, so He rendered worthless their deeds.","tr":"Thalika bi-annahumu ittabaAAoo maaskhata Allaha wakarihoo ridwanahufaahbata aAAmalahum","juz":26,"page":509},{"s":47,"a":29,"key":"47:29","ar":"أَمْ حَسِبَ ٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌ أَن لَّن يُخْرِجَ ٱللَّهُ أَضْغَـٰنَهُمْ","en":"Or do those in whose hearts is disease think that Allāh would never expose their [feelings of] hatred?","tr":"Am hasiba allatheena feequloobihim maradun an lan yukhrija Allahu adghanahum","juz":26,"page":509},{"s":47,"a":30,"key":"47:30","ar":"وَلَوْ نَشَآءُ لَأَرَيْنَـٰكَهُمْ فَلَعَرَفْتَهُم بِسِيمَـٰهُمْ ۚ وَلَتَعْرِفَنَّهُمْ فِى لَحْنِ ٱلْقَوْلِ ۚ وَٱللَّهُ يَعْلَمُ أَعْمَـٰلَكُمْ","en":"And if We willed, We could show them to you, and you would know them by their mark; but you will surely know them by the tone of [their] speech. And Allāh knows your deeds.","tr":"Walaw nashao laaraynakahumfalaAAaraftahum biseemahum walataAArifannahum fee lahnialqawli wallahu yaAAlamu aAAmalakum","juz":26,"page":510},{"s":47,"a":31,"key":"47:31","ar":"وَلَنَبْلُوَنَّكُمْ حَتَّىٰ نَعْلَمَ ٱلْمُجَـٰهِدِينَ مِنكُمْ وَٱلصَّـٰبِرِينَ وَنَبْلُوَا۟ أَخْبَارَكُمْ","en":"And We will surely test you until We make evident those who strive among you [for the cause of Allāh] and the patient, and We will test your affairs.","tr":"Walanabluwannakum hattanaAAlama almujahideena minkum wassabireenawanabluwa akhbarakum","juz":26,"page":510},{"s":47,"a":32,"key":"47:32","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ وَشَآقُّوا۟ ٱلرَّسُولَ مِنۢ بَعْدِ مَا تَبَيَّنَ لَهُمُ ٱلْهُدَىٰ لَن يَضُرُّوا۟ ٱللَّهَ شَيْـًٔا وَسَيُحْبِطُ أَعْمَـٰلَهُمْ","en":"Indeed, those who disbelieved and averted [people] from the path of Allāh and opposed the Messenger after guidance had become clear to them - never will they harm Allāh at all, and He will render worthless their deeds.","tr":"Inna allatheena kafaroo wasaddooAAan sabeeli Allahi washaqqoo arrasoola minbaAAdi ma tabayyana lahumu alhuda lan yadurooAllaha shay-an wasayuhbitu aAAmalahum","juz":26,"page":510},{"s":47,"a":33,"key":"47:33","ar":"۞ يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ أَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ وَلَا تُبْطِلُوٓا۟ أَعْمَـٰلَكُمْ","en":"O you who have believed, obey Allāh and obey the Messenger and do not invalidate your deeds.","tr":"Ya ayyuha allatheena amanooateeAAoo Allaha waateeAAoo arrasoolawala tubtiloo aAAmalakum","juz":26,"page":510},{"s":47,"a":34,"key":"47:34","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ ثُمَّ مَاتُوا۟ وَهُمْ كُفَّارٌ فَلَن يَغْفِرَ ٱللَّهُ لَهُمْ","en":"Indeed, those who disbelieved and averted [people] from the path of Allāh and then died while they were disbelievers - never will Allāh forgive them.","tr":"Inna allatheena kafaroo wasaddooAAan sabeeli Allahi thumma matoo wahum kuffarunfalan yaghfira Allahu lahum","juz":26,"page":510},{"s":47,"a":35,"key":"47:35","ar":"فَلَا تَهِنُوا۟ وَتَدْعُوٓا۟ إِلَى ٱلسَّلْمِ وَأَنتُمُ ٱلْأَعْلَوْنَ وَٱللَّهُ مَعَكُمْ وَلَن يَتِرَكُمْ أَعْمَـٰلَكُمْ","en":"So do not weaken and call for peace while you are superior; and Allāh is with you and will never deprive you of [the reward of] your deeds.","tr":"Fala tahinoo watadAAoo ila assalmiwaantumu al-aAAlawna wallahu maAAakum walanyatirakum aAAmalakum","juz":26,"page":510},{"s":47,"a":36,"key":"47:36","ar":"إِنَّمَا ٱلْحَيَوٰةُ ٱلدُّنْيَا لَعِبٌ وَلَهْوٌ ۚ وَإِن تُؤْمِنُوا۟ وَتَتَّقُوا۟ يُؤْتِكُمْ أُجُورَكُمْ وَلَا يَسْـَٔلْكُمْ أَمْوَٰلَكُمْ","en":"[This] worldly life is only amusement and diversion. And if you believe and fear Allāh, He will give you your rewards and not ask you for your properties.","tr":"Innama alhayatu addunyalaAAibun walahwun wa-in tu/minoo watattaqoo yu/tikum ojoorakumwala yas-alkum amwalakum","juz":26,"page":510},{"s":47,"a":37,"key":"47:37","ar":"إِن يَسْـَٔلْكُمُوهَا فَيُحْفِكُمْ تَبْخَلُوا۟ وَيُخْرِجْ أَضْغَـٰنَكُمْ","en":"If He should ask you for them and press you, you would withhold, and He would expose your hatred [i.e., unwillingness].","tr":"In yas-alkumooha fayuhfikumtabkhaloo wayukhrij adghanakum","juz":26,"page":510},{"s":47,"a":38,"key":"47:38","ar":"هَـٰٓأَنتُمْ هَـٰٓؤُلَآءِ تُدْعَوْنَ لِتُنفِقُوا۟ فِى سَبِيلِ ٱللَّهِ فَمِنكُم مَّن يَبْخَلُ ۖ وَمَن يَبْخَلْ فَإِنَّمَا يَبْخَلُ عَن نَّفْسِهِۦ ۚ وَٱللَّهُ ٱلْغَنِىُّ وَأَنتُمُ ٱلْفُقَرَآءُ ۚ وَإِن تَتَوَلَّوْا۟ يَسْتَبْدِلْ قَوْمًا غَيْرَكُمْ ثُمَّ لَا يَكُونُوٓا۟ أَمْثَـٰلَكُم","en":"Here you are - those invited to spend in the cause of Allāh - but among you are those who withhold [out of greed]. And whoever withholds only withholds [benefit] from himself; and Allāh is the Free of need, while you are the needy. And if you turn away [i.e., refuse], He will replace you with another people; then they will not be the likes of you.","tr":"Ha antum haola-itudAAawna litunfiqoo fee sabeeli Allahi faminkum manyabkhalu waman yabkhal fa-innama yabkhalu AAan nafsihi wallahualghaniyyu waantumu alfuqarao wa-in tatawallaw yastabdilqawman ghayrakum thumma la yakoonoo amthalakum","juz":26,"page":510},{"s":48,"a":1,"key":"48:1","ar":" إِنَّا فَتَحْنَا لَكَ فَتْحًا مُّبِينًا","en":"Indeed, We have given you, [O Muḥammad], a clear conquest1","tr":"Inna fatahna laka fathanmubeena","juz":26,"page":511},{"s":48,"a":2,"key":"48:2","ar":"لِّيَغْفِرَ لَكَ ٱللَّهُ مَا تَقَدَّمَ مِن ذَنۢبِكَ وَمَا تَأَخَّرَ وَيُتِمَّ نِعْمَتَهُۥ عَلَيْكَ وَيَهْدِيَكَ صِرَٰطًا مُّسْتَقِيمًا","en":"That Allāh may forgive for you what preceded of your sin [i.e., errors] and what will follow and complete His favor upon you and guide you to a straight path","tr":"Liyaghfira laka Allahu mataqaddama min thanbika wama taakhkhara wayutimmaniAAmatahu AAalayka wayahdiyaka siratan mustaqeema","juz":26,"page":511},{"s":48,"a":3,"key":"48:3","ar":"وَيَنصُرَكَ ٱللَّهُ نَصْرًا عَزِيزًا","en":"And [that] Allāh may aid you with a mighty victory.","tr":"Wayansuraka Allahu nasranAAazeeza","juz":26,"page":511},{"s":48,"a":4,"key":"48:4","ar":"هُوَ ٱلَّذِىٓ أَنزَلَ ٱلسَّكِينَةَ فِى قُلُوبِ ٱلْمُؤْمِنِينَ لِيَزْدَادُوٓا۟ إِيمَـٰنًا مَّعَ إِيمَـٰنِهِمْ ۗ وَلِلَّهِ جُنُودُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ عَلِيمًا حَكِيمًا","en":"It is He who sent down tranquility into the hearts of the believers that they would increase in faith along with their [present] faith. And to Allāh belong the soldiers of the heavens and the earth, and ever is Allāh Knowing and Wise.","tr":"Huwa allathee anzala assakeenatafee quloobi almu/mineena liyazdadoo eemanan maAAaeemanihim walillahi junoodu assamawatiwal-ardi wakana Allahu AAaleeman hakeema","juz":26,"page":511},{"s":48,"a":5,"key":"48:5","ar":"لِّيُدْخِلَ ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَـٰتِ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا وَيُكَفِّرَ عَنْهُمْ سَيِّـَٔاتِهِمْ ۚ وَكَانَ ذَٰلِكَ عِندَ ٱللَّهِ فَوْزًا عَظِيمًا","en":"[And] that He may admit the believing men and the believing women to gardens beneath which rivers flow to abide therein eternally and remove from them their misdeeds - and ever is that, in the sight of Allāh, a great attainment","tr":"Liyudkhila almu/mineena walmu/minatijannatin tajree min tahtiha al-anharukhalideena feeha wayukaffira AAanhum sayyi-atihimwakana thalika AAinda Allahi fawzan AAatheema","juz":26,"page":511},{"s":48,"a":6,"key":"48:6","ar":"وَيُعَذِّبَ ٱلْمُنَـٰفِقِينَ وَٱلْمُنَـٰفِقَـٰتِ وَٱلْمُشْرِكِينَ وَٱلْمُشْرِكَـٰتِ ٱلظَّآنِّينَ بِٱللَّهِ ظَنَّ ٱلسَّوْءِ ۚ عَلَيْهِمْ دَآئِرَةُ ٱلسَّوْءِ ۖ وَغَضِبَ ٱللَّهُ عَلَيْهِمْ وَلَعَنَهُمْ وَأَعَدَّ لَهُمْ جَهَنَّمَ ۖ وَسَآءَتْ مَصِيرًا","en":"And [that] He may punish the hypocrite men and hypocrite women, and the polytheist men and polytheist women - those who assume about Allāh an assumption of evil nature. Upon them is a misfortune of evil nature; and Allāh has become angry with them and has cursed them and prepared for them Hell, and evil it is as a destination.","tr":"WayuAAaththiba almunafiqeena walmunafiqatiwalmushrikeena walmushrikati aththanneenabillahi thanna assaw-iAAalayhim da-iratu assaw-i waghadiba AllahuAAalayhim walaAAanahum waaAAadda lahum jahannama wasaat maseera","juz":26,"page":511},{"s":48,"a":7,"key":"48:7","ar":"وَلِلَّهِ جُنُودُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمًا","en":"And to Allāh belong the soldiers of the heavens and the earth. And ever is Allāh Exalted in Might and Wise.","tr":"Walillahi junoodu assamawatiwal-ardi wakana Allahu AAazeezan hakeema","juz":26,"page":511},{"s":48,"a":8,"key":"48:8","ar":"إِنَّآ أَرْسَلْنَـٰكَ شَـٰهِدًا وَمُبَشِّرًا وَنَذِيرًا","en":"Indeed, We have sent you as a witness and a bringer of good tidings and a warner","tr":"Inna arsalnaka shahidanwamubashshiran wanatheera","juz":26,"page":511},{"s":48,"a":9,"key":"48:9","ar":"لِّتُؤْمِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَتُعَزِّرُوهُ وَتُوَقِّرُوهُ وَتُسَبِّحُوهُ بُكْرَةً وَأَصِيلًا","en":"That you [people] may believe in Allāh and His Messenger and honor him and respect him [i.e., the Prophet (ﷺ)] and exalt Him [i.e., Allāh] morning and afternoon.","tr":"Litu/minoo billahi warasoolihiwatuAAazziroohu watuwaqqiroohu watusabbihoohu bukratan waaseela","juz":26,"page":511},{"s":48,"a":10,"key":"48:10","ar":"إِنَّ ٱلَّذِينَ يُبَايِعُونَكَ إِنَّمَا يُبَايِعُونَ ٱللَّهَ يَدُ ٱللَّهِ فَوْقَ أَيْدِيهِمْ ۚ فَمَن نَّكَثَ فَإِنَّمَا يَنكُثُ عَلَىٰ نَفْسِهِۦ ۖ وَمَنْ أَوْفَىٰ بِمَا عَـٰهَدَ عَلَيْهُ ٱللَّهَ فَسَيُؤْتِيهِ أَجْرًا عَظِيمًا","en":"Indeed, those who pledge allegiance to you, [O Muḥammad] - they are actually pledging allegiance to Allāh. The hand1 of Allāh is over their hands.2 So he who breaks his word only breaks it to the detriment of himself. And he who fulfills that which he has promised Allāh - He will give him a great reward.","tr":"Inna allatheena yubayiAAoonakainnama yubayiAAoona Allaha yadu Allahifawqa aydeehim faman nakatha fa-innama yankuthu AAalanafsihi waman awfa bima AAahada AAalayhu Allahafasayu/teehi ajran AAatheema","juz":26,"page":512},{"s":48,"a":11,"key":"48:11","ar":"سَيَقُولُ لَكَ ٱلْمُخَلَّفُونَ مِنَ ٱلْأَعْرَابِ شَغَلَتْنَآ أَمْوَٰلُنَا وَأَهْلُونَا فَٱسْتَغْفِرْ لَنَا ۚ يَقُولُونَ بِأَلْسِنَتِهِم مَّا لَيْسَ فِى قُلُوبِهِمْ ۚ قُلْ فَمَن يَمْلِكُ لَكُم مِّنَ ٱللَّهِ شَيْـًٔا إِنْ أَرَادَ بِكُمْ ضَرًّا أَوْ أَرَادَ بِكُمْ نَفْعًۢا ۚ بَلْ كَانَ ٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرًۢا","en":"Those who remained behind1 of the bedouins will say to you, \"Our properties and our families occupied us, so ask forgiveness for us.\" They say with their tongues what is not within their hearts. Say, \"Then who could prevent Allāh at all if He intended for you harm or intended for you benefit? Rather, ever is Allāh, of what you do, Aware.","tr":"Sayaqoolu laka almukhallafoona mina al-aAArabishaghalatna amwaluna waahloona fastaghfirlana yaqooloona bi-alsinatihim ma laysa feequloobihim qul faman yamliku lakum mina Allahi shay-an inarada bikum darran aw arada bikum nafAAanbal kana Allahu bima taAAmaloona khabeera","juz":26,"page":512},{"s":48,"a":12,"key":"48:12","ar":"بَلْ ظَنَنتُمْ أَن لَّن يَنقَلِبَ ٱلرَّسُولُ وَٱلْمُؤْمِنُونَ إِلَىٰٓ أَهْلِيهِمْ أَبَدًا وَزُيِّنَ ذَٰلِكَ فِى قُلُوبِكُمْ وَظَنَنتُمْ ظَنَّ ٱلسَّوْءِ وَكُنتُمْ قَوْمًۢا بُورًا","en":"But you thought that the Messenger and the believers would never return to their families, ever, and that was made pleasing in your hearts. And you assumed an assumption of evil and became a people ruined.\"","tr":"Bal thanantum an lan yanqalibaarrasoolu walmu/minoona ila ahleehimabadan wazuyyina thalika fee quloobikum wathanantumthanna assaw-i wakuntum qawman boora","juz":26,"page":512},{"s":48,"a":13,"key":"48:13","ar":"وَمَن لَّمْ يُؤْمِنۢ بِٱللَّهِ وَرَسُولِهِۦ فَإِنَّآ أَعْتَدْنَا لِلْكَـٰفِرِينَ سَعِيرًا","en":"And whoever has not believed in Allāh and His Messenger - then indeed, We have prepared for the disbelievers a Blaze.","tr":"Waman lam yu/min billahiwarasoolihi fa-inna aAAtadna lilkafireenasaAAeera","juz":26,"page":512},{"s":48,"a":14,"key":"48:14","ar":"وَلِلَّهِ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ يَغْفِرُ لِمَن يَشَآءُ وَيُعَذِّبُ مَن يَشَآءُ ۚ وَكَانَ ٱللَّهُ غَفُورًا رَّحِيمًا","en":"And to Allāh belongs the dominion of the heavens and the earth. He forgives whom He wills and punishes whom He wills. And ever is Allāh Forgiving and Merciful.","tr":"Walillahi mulku assamawatiwal-ardi yaghfiru liman yashao wayuAAaththibuman yashao wakana Allahu ghafooran raheema","juz":26,"page":512},{"s":48,"a":15,"key":"48:15","ar":"سَيَقُولُ ٱلْمُخَلَّفُونَ إِذَا ٱنطَلَقْتُمْ إِلَىٰ مَغَانِمَ لِتَأْخُذُوهَا ذَرُونَا نَتَّبِعْكُمْ ۖ يُرِيدُونَ أَن يُبَدِّلُوا۟ كَلَـٰمَ ٱللَّهِ ۚ قُل لَّن تَتَّبِعُونَا كَذَٰلِكُمْ قَالَ ٱللَّهُ مِن قَبْلُ ۖ فَسَيَقُولُونَ بَلْ تَحْسُدُونَنَا ۚ بَلْ كَانُوا۟ لَا يَفْقَهُونَ إِلَّا قَلِيلًا","en":"Those who remained1 behind will say when you set out toward the war booty to take it, \"Let us follow you.\" They wish to change the words of Allāh. Say, \"Never will you follow us. Thus did Allāh say before.\" So they will say, \"Rather, you envy us.\" But [in fact] they were not understanding except a little.2","tr":"Sayaqoolu almukhallafoona itha intalaqtumila maghanima lita/khuthooha tharoonanattabiAAkum yureedoona an yubaddiloo kalama Allahiqul lan tattabiAAoona kathalikum qala Allahumin qablu fasayaqooloona bal tahsudoonana bal kanoola yafqahoona illa qaleela","juz":26,"page":512},{"s":48,"a":16,"key":"48:16","ar":"قُل لِّلْمُخَلَّفِينَ مِنَ ٱلْأَعْرَابِ سَتُدْعَوْنَ إِلَىٰ قَوْمٍ أُو۟لِى بَأْسٍ شَدِيدٍ تُقَـٰتِلُونَهُمْ أَوْ يُسْلِمُونَ ۖ فَإِن تُطِيعُوا۟ يُؤْتِكُمُ ٱللَّهُ أَجْرًا حَسَنًا ۖ وَإِن تَتَوَلَّوْا۟ كَمَا تَوَلَّيْتُم مِّن قَبْلُ يُعَذِّبْكُمْ عَذَابًا أَلِيمًا","en":"Say to those who remained behind of the bedouins, \"You will be called to [face] a people of great military might; you may fight them, or they will submit.1 So if you obey, Allāh will give you a good reward; but if you turn away as you turned away before, He will punish you with a painful punishment.\"","tr":"Qul lilmukhallafeena mina al-aAArabisatudAAawna ila qawmin olee ba/sin shadeedin tuqatiloonahumaw yuslimoona fa-in tuteeAAoo yu/tikumu Allahuajran hasanan wa-in tatawallaw kama tawallaytum minqablu yuAAaththibkum AAathaban aleema","juz":26,"page":513},{"s":48,"a":17,"key":"48:17","ar":"لَّيْسَ عَلَى ٱلْأَعْمَىٰ حَرَجٌ وَلَا عَلَى ٱلْأَعْرَجِ حَرَجٌ وَلَا عَلَى ٱلْمَرِيضِ حَرَجٌ ۗ وَمَن يُطِعِ ٱللَّهَ وَرَسُولَهُۥ يُدْخِلْهُ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ۖ وَمَن يَتَوَلَّ يُعَذِّبْهُ عَذَابًا أَلِيمًا","en":"There is not upon the blind any guilt or upon the lame any guilt or upon the ill any guilt [for remaining behind]. And whoever obeys Allāh and His Messenger - He will admit him to gardens beneath which rivers flow; but whoever turns away - He will punish him with a painful punishment.","tr":"Laysa AAala al-aAAma harajunwala AAala al-aAAraji harajun walaAAala almareedi harajun waman yutiAAiAllaha warasoolahu yudkhilhu jannatin tajree min tahtihaal-anharu waman yatawalla yuAAaththibhu AAathabanaleema","juz":26,"page":513},{"s":48,"a":18,"key":"48:18","ar":"۞ لَّقَدْ رَضِىَ ٱللَّهُ عَنِ ٱلْمُؤْمِنِينَ إِذْ يُبَايِعُونَكَ تَحْتَ ٱلشَّجَرَةِ فَعَلِمَ مَا فِى قُلُوبِهِمْ فَأَنزَلَ ٱلسَّكِينَةَ عَلَيْهِمْ وَأَثَـٰبَهُمْ فَتْحًا قَرِيبًا","en":"Certainly was Allāh pleased with the believers when they pledged allegiance to you, [O Muḥammad], under the tree, and He knew what was in their hearts, so He sent down tranquility upon them and rewarded them with an imminent conquest1","tr":"Laqad radiya Allahu AAanialmu/mineena ith yubayiAAoonaka tahta ashshajaratifaAAalima ma fee quloobihim faanzala asakeenataAAalayhim waathabahum fathan qareeba","juz":26,"page":513},{"s":48,"a":19,"key":"48:19","ar":"وَمَغَانِمَ كَثِيرَةً يَأْخُذُونَهَا ۗ وَكَانَ ٱللَّهُ عَزِيزًا حَكِيمًا","en":"And much war booty which they will take. And ever is Allāh Exalted in Might and Wise.","tr":"Wamaghanima katheeratan ya/khuthoonahawakana Allahu AAazeezan hakeema","juz":26,"page":513},{"s":48,"a":20,"key":"48:20","ar":"وَعَدَكُمُ ٱللَّهُ مَغَانِمَ كَثِيرَةً تَأْخُذُونَهَا فَعَجَّلَ لَكُمْ هَـٰذِهِۦ وَكَفَّ أَيْدِىَ ٱلنَّاسِ عَنكُمْ وَلِتَكُونَ ءَايَةً لِّلْمُؤْمِنِينَ وَيَهْدِيَكُمْ صِرَٰطًا مُّسْتَقِيمًا","en":"Allāh has promised you much booty that you will take [in the future] and has hastened for you this [victory] and withheld the hands of people from you - that it may be a sign for the believers and [that] He may guide you to a straight path.","tr":"WaAAadakumu Allahu maghanimakatheeratan ta/khuthoonaha faAAajjala lakum hathihiwakaffa aydiya annasi AAankum walitakoona ayatanlilmu/mineena wayahdiyakum siratan mustaqeema","juz":26,"page":513},{"s":48,"a":21,"key":"48:21","ar":"وَأُخْرَىٰ لَمْ تَقْدِرُوا۟ عَلَيْهَا قَدْ أَحَاطَ ٱللَّهُ بِهَا ۚ وَكَانَ ٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرًا","en":"And [He promises] other [victories] that you were [so far] unable to [realize] which Allāh has already encompassed.1 And ever is Allāh, over all things, competent.","tr":"Waokhra lam taqdiroo AAalayhaqad ahata Allahu biha wakana AllahuAAala kulli shay-in qadeera","juz":26,"page":513},{"s":48,"a":22,"key":"48:22","ar":"وَلَوْ قَـٰتَلَكُمُ ٱلَّذِينَ كَفَرُوا۟ لَوَلَّوُا۟ ٱلْأَدْبَـٰرَ ثُمَّ لَا يَجِدُونَ وَلِيًّا وَلَا نَصِيرًا","en":"And if those [Makkans] who disbelieve had fought you, they would have turned their backs [in flight]. Then they would not find a protector or a helper.","tr":"Walaw qatalakumu allatheenakafaroo lawallawoo al-adbara thumma la yajidoonawaliyyan wala naseera","juz":26,"page":513},{"s":48,"a":23,"key":"48:23","ar":"سُنَّةَ ٱللَّهِ ٱلَّتِى قَدْ خَلَتْ مِن قَبْلُ ۖ وَلَن تَجِدَ لِسُنَّةِ ٱللَّهِ تَبْدِيلًا","en":"[This is] the established way of Allāh which has occurred before. And never will you find in the way of Allāh any change.","tr":"Sunnata Allahi allatee qad khalat minqablu walan tajida lisunnati Allahi tabdeela","juz":26,"page":513},{"s":48,"a":24,"key":"48:24","ar":"وَهُوَ ٱلَّذِى كَفَّ أَيْدِيَهُمْ عَنكُمْ وَأَيْدِيَكُمْ عَنْهُم بِبَطْنِ مَكَّةَ مِنۢ بَعْدِ أَنْ أَظْفَرَكُمْ عَلَيْهِمْ ۚ وَكَانَ ٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرًا","en":"And it is He who withheld their hands from you and your hands from them within [the area of] Makkah after He caused you to overcome them. And ever is Allāh, of what you do, Seeing.","tr":"Wahuwa allathee kaffa aydiyahumAAankum waaydiyakum AAanhum bibatni makkata min baAAdi anathfarakum AAalayhim wakana Allahubima taAAmaloona baseera","juz":26,"page":514},{"s":48,"a":25,"key":"48:25","ar":"هُمُ ٱلَّذِينَ كَفَرُوا۟ وَصَدُّوكُمْ عَنِ ٱلْمَسْجِدِ ٱلْحَرَامِ وَٱلْهَدْىَ مَعْكُوفًا أَن يَبْلُغَ مَحِلَّهُۥ ۚ وَلَوْلَا رِجَالٌ مُّؤْمِنُونَ وَنِسَآءٌ مُّؤْمِنَـٰتٌ لَّمْ تَعْلَمُوهُمْ أَن تَطَـُٔوهُمْ فَتُصِيبَكُم مِّنْهُم مَّعَرَّةٌۢ بِغَيْرِ عِلْمٍ ۖ لِّيُدْخِلَ ٱللَّهُ فِى رَحْمَتِهِۦ مَن يَشَآءُ ۚ لَوْ تَزَيَّلُوا۟ لَعَذَّبْنَا ٱلَّذِينَ كَفَرُوا۟ مِنْهُمْ عَذَابًا أَلِيمًا","en":"They are the ones who disbelieved and obstructed you from al-Masjid al-Ḥarām while the offering1 was prevented from reaching its place of sacrifice. And if not for believing men and believing women whom you did not know - that you might trample [i.e., kill] them and there would befall you because of them dishonor without [your] knowledge - [you would have been permitted to enter Makkah]. [This was so] that Allāh might admit to His mercy whom He willed. If they had been apart [from them], We would have punished those who disbelieved among them with painful punishment","tr":"Humu allatheena kafaroo wasaddookumAAani almasjidi alharami walhadyamaAAkoofan an yablugha mahillahu walawla rijalunmu/minoona wanisaon mu/minatun lam taAAlamoohum antataoohum fatuseebakum minhum maAAarratun bighayriAAilmin liyudkhila Allahu fee rahmatihi man yashaolaw tazayyaloo laAAaththabna allatheenakafaroo minhum AAathaban aleema","juz":26,"page":514},{"s":48,"a":26,"key":"48:26","ar":"إِذْ جَعَلَ ٱلَّذِينَ كَفَرُوا۟ فِى قُلُوبِهِمُ ٱلْحَمِيَّةَ حَمِيَّةَ ٱلْجَـٰهِلِيَّةِ فَأَنزَلَ ٱللَّهُ سَكِينَتَهُۥ عَلَىٰ رَسُولِهِۦ وَعَلَى ٱلْمُؤْمِنِينَ وَأَلْزَمَهُمْ كَلِمَةَ ٱلتَّقْوَىٰ وَكَانُوٓا۟ أَحَقَّ بِهَا وَأَهْلَهَا ۚ وَكَانَ ٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمًا","en":"When those who disbelieved had put into their hearts chauvinism - the chauvinism of the time of ignorance. But Allāh sent down His tranquility upon His Messenger and upon the believers and imposed upon them the word of righteousness, and they were more deserving of it and worthy of it. And ever is Allāh, of all things, Knowing.","tr":"Ith jaAAala allatheena kafaroofee quloobihimu alhamiyyata hamiyyata aljahiliyyatifaanzala Allahu sakeenatahu AAala rasoolihi waAAalaalmu/mineena waalzamahum kalimata attaqwa wakanooahaqqa biha waahlaha wakana Allahubikulli shay-in AAaleema","juz":26,"page":514},{"s":48,"a":27,"key":"48:27","ar":"لَّقَدْ صَدَقَ ٱللَّهُ رَسُولَهُ ٱلرُّءْيَا بِٱلْحَقِّ ۖ لَتَدْخُلُنَّ ٱلْمَسْجِدَ ٱلْحَرَامَ إِن شَآءَ ٱللَّهُ ءَامِنِينَ مُحَلِّقِينَ رُءُوسَكُمْ وَمُقَصِّرِينَ لَا تَخَافُونَ ۖ فَعَلِمَ مَا لَمْ تَعْلَمُوا۟ فَجَعَلَ مِن دُونِ ذَٰلِكَ فَتْحًا قَرِيبًا","en":"Certainly has Allāh showed to His Messenger the vision [i.e., dream] in truth. You will surely enter al-Masjid al-Ḥarām, if Allāh wills, in safety, with your heads shaved and [hair] shortened,1 not fearing [anyone]. He knew what you did not know and has arranged before that a conquest near [at hand].","tr":"Laqad sadaqa Allahu rasoolahuarru/ya bilhaqqi latadkhulunnaalmasjida alharama in shaa Allahu amineenamuhalliqeena ruoosakum wamuqassireena latakhafoona faAAalima ma lam taAAlamoo fajaAAala mindooni thalika fathan qareeba","juz":26,"page":514},{"s":48,"a":28,"key":"48:28","ar":"هُوَ ٱلَّذِىٓ أَرْسَلَ رَسُولَهُۥ بِٱلْهُدَىٰ وَدِينِ ٱلْحَقِّ لِيُظْهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ ۚ وَكَفَىٰ بِٱللَّهِ شَهِيدًا","en":"It is He who sent His Messenger with guidance and the religion of truth to manifest it over all religion. And sufficient is Allāh as Witness.","tr":"Huwa allathee arsala rasoolahu bilhudawadeeni alhaqqi liyuthhirahu AAala addeenikullihi wakafa billahi shaheeda","juz":26,"page":514},{"s":48,"a":29,"key":"48:29","ar":"مُّحَمَّدٌ رَّسُولُ ٱللَّهِ ۚ وَٱلَّذِينَ مَعَهُۥٓ أَشِدَّآءُ عَلَى ٱلْكُفَّارِ رُحَمَآءُ بَيْنَهُمْ ۖ تَرَىٰهُمْ رُكَّعًا سُجَّدًا يَبْتَغُونَ فَضْلًا مِّنَ ٱللَّهِ وَرِضْوَٰنًا ۖ سِيمَاهُمْ فِى وُجُوهِهِم مِّنْ أَثَرِ ٱلسُّجُودِ ۚ ذَٰلِكَ مَثَلُهُمْ فِى ٱلتَّوْرَىٰةِ ۚ وَمَثَلُهُمْ فِى ٱلْإِنجِيلِ كَزَرْعٍ أَخْرَجَ شَطْـَٔهُۥ فَـَٔازَرَهُۥ فَٱسْتَغْلَظَ فَٱسْتَوَىٰ عَلَىٰ سُوقِهِۦ يُعْجِبُ ٱلزُّرَّاعَ لِيَغِيظَ بِهِمُ ٱلْكُفَّارَ ۗ وَعَدَ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ مِنْهُم مَّغْفِرَةً وَأَجْرًا عَظِيمًۢا","en":"Muḥammad is the Messenger of Allāh; and those with him are forceful against the disbelievers, merciful among themselves. You see them bowing and prostrating [in prayer], seeking bounty from Allāh and [His] pleasure. Their sign is in their faces from the effect of prostration [i.e., prayer]. That is their description in the Torah. And their description in the Gospel is as a plant which produces its offshoots and strengthens them so they grow firm and stand upon their stalks, delighting the sowers - so that He [i.e., Allāh] may enrage by them1 the disbelievers. Allāh has promised those who believe and do righteous deeds among them forgiveness and a great reward.","tr":"Muhammadun rasoolu Allahi wallatheenamaAAahu ashiddao AAala alkuffari ruhamaobaynahum tarahum rukkaAAan sujjadan yabtaghoona fadlanmina Allahi waridwanan seemahum feewujoohihim min athari assujoodi thalika mathaluhumfee attawrati wamathaluhum fee al-injeelikazarAAin akhraja shat-ahu faazarahu fastaghlathafastawa AAala sooqihi yuAAjibu azzurraAAaliyagheetha bihimu alkuffara waAAada Allahuallatheena amanoo waAAamiloo assalihatiminhum maghfiratan waajran AAatheema","juz":26,"page":515},{"s":49,"a":1,"key":"49:1","ar":" يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تُقَدِّمُوا۟ بَيْنَ يَدَىِ ٱللَّهِ وَرَسُولِهِۦ ۖ وَٱتَّقُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ سَمِيعٌ عَلِيمٌ","en":"O you who have believed, do not put [yourselves] before Allāh and His Messenger1 but fear Allāh. Indeed, Allāh is Hearing and Knowing.","tr":"Ya ayyuha allatheena amanoola tuqaddimoo bayna yadayi Allahi warasoolihi wattaqooAllaha inna Allaha sameeAAun AAaleem","juz":26,"page":515},{"s":49,"a":2,"key":"49:2","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَرْفَعُوٓا۟ أَصْوَٰتَكُمْ فَوْقَ صَوْتِ ٱلنَّبِىِّ وَلَا تَجْهَرُوا۟ لَهُۥ بِٱلْقَوْلِ كَجَهْرِ بَعْضِكُمْ لِبَعْضٍ أَن تَحْبَطَ أَعْمَـٰلُكُمْ وَأَنتُمْ لَا تَشْعُرُونَ","en":"O you who have believed, do not raise your voices above the voice of the Prophet or be loud to him in speech like the loudness of some of you to others, lest your deeds become worthless while you perceive not.","tr":"Ya ayyuha allatheena amanoola tarfaAAoo aswatakum fawqa sawti annabiyyiwala tajharoo lahu bilqawli kajahri baAAdikumlibaAAdin an tahbata aAAmalukumwaantum la tashAAuroon","juz":26,"page":515},{"s":49,"a":3,"key":"49:3","ar":"إِنَّ ٱلَّذِينَ يَغُضُّونَ أَصْوَٰتَهُمْ عِندَ رَسُولِ ٱللَّهِ أُو۟لَـٰٓئِكَ ٱلَّذِينَ ٱمْتَحَنَ ٱللَّهُ قُلُوبَهُمْ لِلتَّقْوَىٰ ۚ لَهُم مَّغْفِرَةٌ وَأَجْرٌ عَظِيمٌ","en":"Indeed, those who lower their voices before the Messenger of Allāh - they are the ones whose hearts Allāh has tested for righteousness. For them is forgiveness and great reward.","tr":"Inna allatheena yaghuddoona aswatahumAAinda rasooli Allahi ola-ika allatheenaimtahana Allahu quloobahum littaqwalahum maghfiratun waajrun AAatheem","juz":26,"page":515},{"s":49,"a":4,"key":"49:4","ar":"إِنَّ ٱلَّذِينَ يُنَادُونَكَ مِن وَرَآءِ ٱلْحُجُرَٰتِ أَكْثَرُهُمْ لَا يَعْقِلُونَ","en":"Indeed, those who call you, [O Muḥammad], from behind the chambers - most of them do not use reason.","tr":"Inna allatheena yunadoonaka minwara-i alhujurati aktharuhum layaAAqiloon","juz":26,"page":515},{"s":49,"a":5,"key":"49:5","ar":"وَلَوْ أَنَّهُمْ صَبَرُوا۟ حَتَّىٰ تَخْرُجَ إِلَيْهِمْ لَكَانَ خَيْرًا لَّهُمْ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"And if they had been patient until you [could] come out to them, it would have been better for them. But Allāh is Forgiving and Merciful.","tr":"Walaw annahum sabaroo hattatakhruja ilayhim lakana khayran lahum wallahughafoorun raheem","juz":26,"page":516},{"s":49,"a":6,"key":"49:6","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِن جَآءَكُمْ فَاسِقٌۢ بِنَبَإٍ فَتَبَيَّنُوٓا۟ أَن تُصِيبُوا۟ قَوْمًۢا بِجَهَـٰلَةٍ فَتُصْبِحُوا۟ عَلَىٰ مَا فَعَلْتُمْ نَـٰدِمِينَ","en":"O you who have believed, if there comes to you a disobedient one with information, investigate, lest you harm a people out of ignorance and become, over what you have done, regretful.","tr":"Ya ayyuha allatheena amanooin jaakum fasiqun binaba-in fatabayyanoo an tuseebooqawman bijahalatin fatusbihoo AAala mafaAAaltum nadimeen","juz":26,"page":516},{"s":49,"a":7,"key":"49:7","ar":"وَٱعْلَمُوٓا۟ أَنَّ فِيكُمْ رَسُولَ ٱللَّهِ ۚ لَوْ يُطِيعُكُمْ فِى كَثِيرٍ مِّنَ ٱلْأَمْرِ لَعَنِتُّمْ وَلَـٰكِنَّ ٱللَّهَ حَبَّبَ إِلَيْكُمُ ٱلْإِيمَـٰنَ وَزَيَّنَهُۥ فِى قُلُوبِكُمْ وَكَرَّهَ إِلَيْكُمُ ٱلْكُفْرَ وَٱلْفُسُوقَ وَٱلْعِصْيَانَ ۚ أُو۟لَـٰٓئِكَ هُمُ ٱلرَّٰشِدُونَ","en":"And know that among you is the Messenger of Allāh. If he were to obey you in much of the matter, you would be in difficulty, but Allāh has endeared to you the faith and has made it pleasing in your hearts and has made hateful to you disbelief, defiance and disobedience. Those are the [rightly] guided.","tr":"WaAAlamoo anna feekum rasoola Allahilaw yuteeAAukum fee katheerin mina al-amri laAAanittum walakinnaAllaha habbaba ilaykumu al-eemanawazayyanahu fee quloobikum wakarraha ilaykumu alkufra walfusooqawalAAisyana ola-ika humu arrashidoon","juz":26,"page":516},{"s":49,"a":8,"key":"49:8","ar":"فَضْلًا مِّنَ ٱللَّهِ وَنِعْمَةً ۚ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"[It is] as bounty from Allāh and favor. And Allāh is Knowing and Wise.","tr":"Fadlan mina Allahi waniAAmatanwallahu AAaleemun hakeem","juz":26,"page":516},{"s":49,"a":9,"key":"49:9","ar":"وَإِن طَآئِفَتَانِ مِنَ ٱلْمُؤْمِنِينَ ٱقْتَتَلُوا۟ فَأَصْلِحُوا۟ بَيْنَهُمَا ۖ فَإِنۢ بَغَتْ إِحْدَىٰهُمَا عَلَى ٱلْأُخْرَىٰ فَقَـٰتِلُوا۟ ٱلَّتِى تَبْغِى حَتَّىٰ تَفِىٓءَ إِلَىٰٓ أَمْرِ ٱللَّهِ ۚ فَإِن فَآءَتْ فَأَصْلِحُوا۟ بَيْنَهُمَا بِٱلْعَدْلِ وَأَقْسِطُوٓا۟ ۖ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُقْسِطِينَ","en":"And if two factions among the believers should fight, then make settlement between the two. But if one of them oppresses the other, then fight against the one that oppresses until it returns to the ordinance of Allāh. And if it returns, then make settlement between them in justice and act justly. Indeed, Allāh loves those who act justly.","tr":"Wa-in ta-ifatani minaalmu/mineena iqtataloo faaslihoo baynahumafa-in baghat ihdahuma AAala al-okhrafaqatiloo allatee tabghee hatta tafee-a ilaamri Allahi fa-in faat faaslihoobaynahuma bilAAadli waaqsitoo inna Allahayuhibbu almuqsiteen","juz":26,"page":516},{"s":49,"a":10,"key":"49:10","ar":"إِنَّمَا ٱلْمُؤْمِنُونَ إِخْوَةٌ فَأَصْلِحُوا۟ بَيْنَ أَخَوَيْكُمْ ۚ وَٱتَّقُوا۟ ٱللَّهَ لَعَلَّكُمْ تُرْحَمُونَ","en":"The believers are but brothers, so make settlement between your brothers. And fear Allāh that you may receive mercy.","tr":"Innama almu/minoona ikhwatun faaslihoobayna akhawaykum wattaqoo Allaha laAAallakum turhamoon","juz":26,"page":516},{"s":49,"a":11,"key":"49:11","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا يَسْخَرْ قَوْمٌ مِّن قَوْمٍ عَسَىٰٓ أَن يَكُونُوا۟ خَيْرًا مِّنْهُمْ وَلَا نِسَآءٌ مِّن نِّسَآءٍ عَسَىٰٓ أَن يَكُنَّ خَيْرًا مِّنْهُنَّ ۖ وَلَا تَلْمِزُوٓا۟ أَنفُسَكُمْ وَلَا تَنَابَزُوا۟ بِٱلْأَلْقَـٰبِ ۖ بِئْسَ ٱلِٱسْمُ ٱلْفُسُوقُ بَعْدَ ٱلْإِيمَـٰنِ ۚ وَمَن لَّمْ يَتُبْ فَأُو۟لَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ","en":"O you who have believed, let not a people ridicule [another] people; perhaps they may be better than them; nor let women ridicule [other] women; perhaps they may be better than them. And do not insult one another and do not call each other by [offensive] nicknames. Wretched is the name [i.e., mention] of disobedience after [one's] faith. And whoever does not repent - then it is those who are the wrongdoers.","tr":"Ya ayyuha allatheena amanoola yaskhar qawmun min qawmin AAasa an yakoonookhayran minhum wala nisaon min nisa-in AAasaan yakunna khayran minhunna wala talmizoo anfusakum walatanabazoo bil-alqabi bi/sa al-ismualfusooqu baAAda al-eemani waman lam yatub faola-ikahumu aththalimoon","juz":26,"page":516},{"s":49,"a":12,"key":"49:12","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱجْتَنِبُوا۟ كَثِيرًا مِّنَ ٱلظَّنِّ إِنَّ بَعْضَ ٱلظَّنِّ إِثْمٌ ۖ وَلَا تَجَسَّسُوا۟ وَلَا يَغْتَب بَّعْضُكُم بَعْضًا ۚ أَيُحِبُّ أَحَدُكُمْ أَن يَأْكُلَ لَحْمَ أَخِيهِ مَيْتًا فَكَرِهْتُمُوهُ ۚ وَٱتَّقُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ تَوَّابٌ رَّحِيمٌ","en":"O you who have believed, avoid much [negative] assumption. Indeed, some assumption is sin. And do not spy or backbite each other. Would one of you like to eat the flesh of his brother when dead? You would detest it. And fear Allāh; indeed, Allāh is Accepting of Repentance and Merciful.","tr":"Ya ayyuha allatheena amanooijtaniboo katheeran mina aththanni innabaAAda aththanni ithmun walatajassasoo wala yaghtab baAAdukum baAAdanayuhibbu ahadukum an ya/kula lahma akheehimaytan fakarihtumoohu wattaqoo Allaha inna Allahatawwabun raheem","juz":26,"page":517},{"s":49,"a":13,"key":"49:13","ar":"يَـٰٓأَيُّهَا ٱلنَّاسُ إِنَّا خَلَقْنَـٰكُم مِّن ذَكَرٍ وَأُنثَىٰ وَجَعَلْنَـٰكُمْ شُعُوبًا وَقَبَآئِلَ لِتَعَارَفُوٓا۟ ۚ إِنَّ أَكْرَمَكُمْ عِندَ ٱللَّهِ أَتْقَىٰكُمْ ۚ إِنَّ ٱللَّهَ عَلِيمٌ خَبِيرٌ","en":"O mankind, indeed We have created you from male and female and made you peoples and tribes that you may know one another. Indeed, the most noble of you in the sight of Allāh is the most righteous1 of you. Indeed, Allāh is Knowing and Aware.","tr":"Ya ayyuha annasuinna khalaqnakum min thakarin waonthawajaAAalnakum shuAAooban waqaba-ila litaAAarafooinna akramakum AAinda Allahi atqakum inna AllahaAAaleemun khabeer","juz":26,"page":517},{"s":49,"a":14,"key":"49:14","ar":"۞ قَالَتِ ٱلْأَعْرَابُ ءَامَنَّا ۖ قُل لَّمْ تُؤْمِنُوا۟ وَلَـٰكِن قُولُوٓا۟ أَسْلَمْنَا وَلَمَّا يَدْخُلِ ٱلْإِيمَـٰنُ فِى قُلُوبِكُمْ ۖ وَإِن تُطِيعُوا۟ ٱللَّهَ وَرَسُولَهُۥ لَا يَلِتْكُم مِّنْ أَعْمَـٰلِكُمْ شَيْـًٔا ۚ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"The bedouins say, \"We have believed.\" Say, \"You have not [yet] believed; but say [instead], 'We have submitted,' for faith has not yet entered your hearts. And if you obey Allāh and His Messenger, He will not deprive you from your deeds1 of anything. Indeed, Allāh is Forgiving and Merciful.\"","tr":"Qalati al-aAArabu amannaqul lam tu/minoo walakin qooloo aslamna walammayadkhuli al-eemanu fee quloobikum wa-in tuteeAAooAllaha warasoolahu la yalitkum min aAAmalikumshay-an inna Allaha ghafoorun raheem","juz":26,"page":517},{"s":49,"a":15,"key":"49:15","ar":"إِنَّمَا ٱلْمُؤْمِنُونَ ٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ ثُمَّ لَمْ يَرْتَابُوا۟ وَجَـٰهَدُوا۟ بِأَمْوَٰلِهِمْ وَأَنفُسِهِمْ فِى سَبِيلِ ٱللَّهِ ۚ أُو۟لَـٰٓئِكَ هُمُ ٱلصَّـٰدِقُونَ","en":"The believers are only the ones who have believed in Allāh and His Messenger and then doubt not but strive with their properties and their lives in the cause of Allāh. It is those who are the truthful.","tr":"Innama almu/minoona allatheenaamanoo billahi warasoolihi thumma lam yartaboowajahadoo bi-amwalihim waanfusihim fee sabeeli Allahiola-ika humu assadiqoon","juz":26,"page":517},{"s":49,"a":16,"key":"49:16","ar":"قُلْ أَتُعَلِّمُونَ ٱللَّهَ بِدِينِكُمْ وَٱللَّهُ يَعْلَمُ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۚ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"Say, \"Would you acquaint Allāh with your religion while Allāh knows whatever is in the heavens and whatever is on the earth, and Allāh is Knowing of all things?\"","tr":"Qul atuAAallimoona Allaha bideenikumwallahu yaAAlamu ma fee assamawatiwama fee al-ardi wallahu bikullishay-in AAaleem","juz":26,"page":517},{"s":49,"a":17,"key":"49:17","ar":"يَمُنُّونَ عَلَيْكَ أَنْ أَسْلَمُوا۟ ۖ قُل لَّا تَمُنُّوا۟ عَلَىَّ إِسْلَـٰمَكُم ۖ بَلِ ٱللَّهُ يَمُنُّ عَلَيْكُمْ أَنْ هَدَىٰكُمْ لِلْإِيمَـٰنِ إِن كُنتُمْ صَـٰدِقِينَ","en":"They consider it a favor to you that they have accepted Islām. Say, \"Do not consider your Islām a favor to me. Rather, Allāh has conferred favor upon you that He has guided you to the faith, if you should be truthful.\"","tr":"Yamunnoona AAalayka an aslamoo qul latamunnoo AAalayya islamakum bali Allahu yamunnuAAalaykum an hadakum lil-eemani in kuntum sadiqeen","juz":26,"page":517},{"s":49,"a":18,"key":"49:18","ar":"إِنَّ ٱللَّهَ يَعْلَمُ غَيْبَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَٱللَّهُ بَصِيرٌۢ بِمَا تَعْمَلُونَ","en":"Indeed, Allāh knows the unseen [aspects] of the heavens and the earth. And Allāh is Seeing of what you do.","tr":"Inna Allaha yaAAlamu ghayba assamawatiwal-ardi wallahu baseerunbima taAAmaloon","juz":26,"page":517},{"s":50,"a":1,"key":"50:1","ar":" قٓ ۚ وَٱلْقُرْءَانِ ٱلْمَجِيدِ","en":"Qāf.1 By the honored Qur’ān...2","tr":"Qaf walqur-ani almajeed","juz":26,"page":518},{"s":50,"a":2,"key":"50:2","ar":"بَلْ عَجِبُوٓا۟ أَن جَآءَهُم مُّنذِرٌ مِّنْهُمْ فَقَالَ ٱلْكَـٰفِرُونَ هَـٰذَا شَىْءٌ عَجِيبٌ","en":"But they wonder that there has come to them a warner from among themselves, and the disbelievers say, \"This is an amazing thing.","tr":"Bal AAajiboo an jaahum munthirunminhum faqala alkafiroona hatha shay-onAAajeeb","juz":26,"page":518},{"s":50,"a":3,"key":"50:3","ar":"أَءِذَا مِتْنَا وَكُنَّا تُرَابًا ۖ ذَٰلِكَ رَجْعٌۢ بَعِيدٌ","en":"When we have died and have become dust, [we will return to life]? That is a distant [i.e., unlikely] return.\"","tr":"A-itha mitna wakunna turabanthalika rajAAun baAAeed","juz":26,"page":518},{"s":50,"a":4,"key":"50:4","ar":"قَدْ عَلِمْنَا مَا تَنقُصُ ٱلْأَرْضُ مِنْهُمْ ۖ وَعِندَنَا كِتَـٰبٌ حَفِيظٌۢ","en":"We know what the earth diminishes [i.e., consumes] of them, and with Us is a retaining record.","tr":"Qad AAalimna ma tanqusual-ardu minhum waAAindana kitabun hafeeth","juz":26,"page":518},{"s":50,"a":5,"key":"50:5","ar":"بَلْ كَذَّبُوا۟ بِٱلْحَقِّ لَمَّا جَآءَهُمْ فَهُمْ فِىٓ أَمْرٍ مَّرِيجٍ","en":"But they denied the truth when it came to them, so they are in a confused condition.","tr":"Bal kaththaboo bilhaqqilamma jaahum fahum fee amrin mareej","juz":26,"page":518},{"s":50,"a":6,"key":"50:6","ar":"أَفَلَمْ يَنظُرُوٓا۟ إِلَى ٱلسَّمَآءِ فَوْقَهُمْ كَيْفَ بَنَيْنَـٰهَا وَزَيَّنَّـٰهَا وَمَا لَهَا مِن فُرُوجٍ","en":"Have they not looked at the heaven above them - how We structured it and adorned it and [how] it has no rifts?","tr":"Afalam yanthuroo ila assama-ifawqahum kayfa banaynaha wazayyannahawama laha min furooj","juz":26,"page":518},{"s":50,"a":7,"key":"50:7","ar":"وَٱلْأَرْضَ مَدَدْنَـٰهَا وَأَلْقَيْنَا فِيهَا رَوَٰسِىَ وَأَنۢبَتْنَا فِيهَا مِن كُلِّ زَوْجٍۭ بَهِيجٍ","en":"And the earth - We spread it out and cast therein firmly set mountains and made grow therein [something] of every beautiful kind,","tr":"Wal-arda madadnahawaalqayna feeha rawasiya waanbatnafeeha min kulli zawjin baheej","juz":26,"page":518},{"s":50,"a":8,"key":"50:8","ar":"تَبْصِرَةً وَذِكْرَىٰ لِكُلِّ عَبْدٍ مُّنِيبٍ","en":"Giving insight and a reminder for every servant who turns [to Allāh].","tr":"Tabsiratan wathikralikulli AAabdin muneeb","juz":26,"page":518},{"s":50,"a":9,"key":"50:9","ar":"وَنَزَّلْنَا مِنَ ٱلسَّمَآءِ مَآءً مُّبَـٰرَكًا فَأَنۢبَتْنَا بِهِۦ جَنَّـٰتٍ وَحَبَّ ٱلْحَصِيدِ","en":"And We have sent down blessed rain from the sky and made grow thereby gardens and grain from the harvest","tr":"Wanazzalna mina assama-imaan mubarakan faanbatna bihi jannatinwahabba alhaseed","juz":26,"page":518},{"s":50,"a":10,"key":"50:10","ar":"وَٱلنَّخْلَ بَاسِقَـٰتٍ لَّهَا طَلْعٌ نَّضِيدٌ","en":"And lofty palm trees having fruit arranged in layers -","tr":"Wannakhla basiqatinlaha talAAun nadeed","juz":26,"page":518},{"s":50,"a":11,"key":"50:11","ar":"رِّزْقًا لِّلْعِبَادِ ۖ وَأَحْيَيْنَا بِهِۦ بَلْدَةً مَّيْتًا ۚ كَذَٰلِكَ ٱلْخُرُوجُ","en":"As provision for the servants, and We have given life thereby to a dead land. Thus is the emergence [i.e., resurrection].","tr":"Rizqan lilAAibadi waahyaynabihi baldatan maytan kathalika alkhurooj","juz":26,"page":518},{"s":50,"a":12,"key":"50:12","ar":"كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍ وَأَصْحَـٰبُ ٱلرَّسِّ وَثَمُودُ","en":"The people of Noah denied before them,1 and the companions of the well2 and Thamūd","tr":"Kaththabat qablahum qawmu noohinwaas-habu arrassi wathamood","juz":26,"page":518},{"s":50,"a":13,"key":"50:13","ar":"وَعَادٌ وَفِرْعَوْنُ وَإِخْوَٰنُ لُوطٍ","en":"And ʿAad and Pharaoh and the brothers [i.e., people] of Lot","tr":"WaAAadun wafirAAawnu wa-ikhwanuloot","juz":26,"page":518},{"s":50,"a":14,"key":"50:14","ar":"وَأَصْحَـٰبُ ٱلْأَيْكَةِ وَقَوْمُ تُبَّعٍ ۚ كُلٌّ كَذَّبَ ٱلرُّسُلَ فَحَقَّ وَعِيدِ","en":"And the companions of the thicket and the people of Tubbaʿ. All denied the messengers, so My threat was justly fulfilled.","tr":"Waas-habu al-aykati waqawmutubbaAAin kullun kaththaba arrusula fahaqqawaAAeed","juz":26,"page":518},{"s":50,"a":15,"key":"50:15","ar":"أَفَعَيِينَا بِٱلْخَلْقِ ٱلْأَوَّلِ ۚ بَلْ هُمْ فِى لَبْسٍ مِّنْ خَلْقٍ جَدِيدٍ","en":"Did We fail in the first creation? But they are in confusion over a new creation.","tr":"AfaAAayeena bilkhalqial-awwali bal hum fee labsin min khalqin jadeed","juz":26,"page":518},{"s":50,"a":16,"key":"50:16","ar":"وَلَقَدْ خَلَقْنَا ٱلْإِنسَـٰنَ وَنَعْلَمُ مَا تُوَسْوِسُ بِهِۦ نَفْسُهُۥ ۖ وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنْ حَبْلِ ٱلْوَرِيدِ","en":"And We have already created man and know what his soul whispers to him, and We are closer1 to him than [his] jugular vein.","tr":"Walaqad khalaqna al-insanawanaAAlamu ma tuwaswisu bihi nafsuhu wanahnu aqrabuilayhi min habli alwareed","juz":26,"page":519},{"s":50,"a":17,"key":"50:17","ar":"إِذْ يَتَلَقَّى ٱلْمُتَلَقِّيَانِ عَنِ ٱلْيَمِينِ وَعَنِ ٱلشِّمَالِ قَعِيدٌ","en":"When the two receivers [i.e., recording angels] receive,1 seated on the right and on the left.","tr":"Ith yatalaqqa almutalaqqiyaniAAani alyameeni waAAani ashshimali qaAAeed","juz":26,"page":519},{"s":50,"a":18,"key":"50:18","ar":"مَّا يَلْفِظُ مِن قَوْلٍ إِلَّا لَدَيْهِ رَقِيبٌ عَتِيدٌ","en":"He [i.e., man] utters no word except that with him is an observer prepared [to record].","tr":"Ma yalfithu min qawlinilla ladayhi raqeebun AAateed","juz":26,"page":519},{"s":50,"a":19,"key":"50:19","ar":"وَجَآءَتْ سَكْرَةُ ٱلْمَوْتِ بِٱلْحَقِّ ۖ ذَٰلِكَ مَا كُنتَ مِنْهُ تَحِيدُ","en":"And the intoxication of death will bring the truth; that is what you were trying to avoid.","tr":"Wajaat sakratu almawti bilhaqqithalika ma kunta minhu taheed","juz":26,"page":519},{"s":50,"a":20,"key":"50:20","ar":"وَنُفِخَ فِى ٱلصُّورِ ۚ ذَٰلِكَ يَوْمُ ٱلْوَعِيدِ","en":"And the Horn will be blown. That is the Day of [carrying out] the threat.","tr":"Wanufikha fee assoori thalikayawmu alwaAAeed","juz":26,"page":519},{"s":50,"a":21,"key":"50:21","ar":"وَجَآءَتْ كُلُّ نَفْسٍ مَّعَهَا سَآئِقٌ وَشَهِيدٌ","en":"And every soul will come, with it a driver and a witness.1","tr":"Wajaat kullu nafsin maAAaha sa-iqunwashaheed","juz":26,"page":519},{"s":50,"a":22,"key":"50:22","ar":"لَّقَدْ كُنتَ فِى غَفْلَةٍ مِّنْ هَـٰذَا فَكَشَفْنَا عَنكَ غِطَآءَكَ فَبَصَرُكَ ٱلْيَوْمَ حَدِيدٌ","en":"[It will be said], \"You were certainly in unmindfulness of this, and We have removed from you your cover,1 so your sight, this Day, is sharp.\"","tr":"Laqad kunta fee ghaflatin min hathafakashafna AAanka ghitaaka fabasarukaalyawma hadeed","juz":26,"page":519},{"s":50,"a":23,"key":"50:23","ar":"وَقَالَ قَرِينُهُۥ هَـٰذَا مَا لَدَىَّ عَتِيدٌ","en":"And his companion, [the angel], will say, \"This [record] is what is with me, prepared.\"","tr":"Waqala qareenuhu hatha maladayya AAateed","juz":26,"page":519},{"s":50,"a":24,"key":"50:24","ar":"أَلْقِيَا فِى جَهَنَّمَ كُلَّ كَفَّارٍ عَنِيدٍ","en":"[Allāh will say], \"Throw into Hell every obstinate disbeliever,","tr":"Alqiya fee jahannama kulla kaffarinAAaneed","juz":26,"page":519},{"s":50,"a":25,"key":"50:25","ar":"مَّنَّاعٍ لِّلْخَيْرِ مُعْتَدٍ مُّرِيبٍ","en":"Preventer of good, aggressor, and doubter,","tr":"MannaAAin lilkhayri muAAtadin mureeb","juz":26,"page":519},{"s":50,"a":26,"key":"50:26","ar":"ٱلَّذِى جَعَلَ مَعَ ٱللَّهِ إِلَـٰهًا ءَاخَرَ فَأَلْقِيَاهُ فِى ٱلْعَذَابِ ٱلشَّدِيدِ","en":"Who made [as equal] with Allāh another deity; then throw him into the severe punishment.\"","tr":"Allathee jaAAala maAAa Allahiilahan akhara faalqiyahu fee alAAathabiashshadeed","juz":26,"page":519},{"s":50,"a":27,"key":"50:27","ar":"۞ قَالَ قَرِينُهُۥ رَبَّنَا مَآ أَطْغَيْتُهُۥ وَلَـٰكِن كَانَ فِى ضَلَـٰلٍۭ بَعِيدٍ","en":"His [devil] companion will say, \"Our Lord, I did not make him transgress, but he [himself] was in extreme error.\"","tr":"Qala qareenuhu rabbana maatghaytuhu walakin kana fee dalalinbaAAeed","juz":26,"page":519},{"s":50,"a":28,"key":"50:28","ar":"قَالَ لَا تَخْتَصِمُوا۟ لَدَىَّ وَقَدْ قَدَّمْتُ إِلَيْكُم بِٱلْوَعِيدِ","en":"[Allāh] will say, \"Do not dispute before Me, while I had already presented to you the threat [i.e., warning].","tr":"Qala la takhtasimooladayya waqad qaddamtu ilaykum bilwaAAeed","juz":26,"page":519},{"s":50,"a":29,"key":"50:29","ar":"مَا يُبَدَّلُ ٱلْقَوْلُ لَدَىَّ وَمَآ أَنَا۠ بِظَلَّـٰمٍ لِّلْعَبِيدِ","en":"The word [i.e., decree] will not be changed with Me, and never will I be unjust to the servants.\"","tr":"Ma yubaddalu alqawlu ladayya wamaana bithallamin lilAAabeed","juz":26,"page":519},{"s":50,"a":30,"key":"50:30","ar":"يَوْمَ نَقُولُ لِجَهَنَّمَ هَلِ ٱمْتَلَأْتِ وَتَقُولُ هَلْ مِن مَّزِيدٍ","en":"On the Day We will say to Hell, \"Have you been filled?\" and it will say, \"Are there some more,\"","tr":"Yawma naqoolu lijahannama hali imtala/tiwataqoolu hal min mazeed","juz":26,"page":519},{"s":50,"a":31,"key":"50:31","ar":"وَأُزْلِفَتِ ٱلْجَنَّةُ لِلْمُتَّقِينَ غَيْرَ بَعِيدٍ","en":"And Paradise will be brought near to the righteous, not far,","tr":"Waozlifati aljannatu lilmuttaqeena ghayrabaAAeed","juz":26,"page":519},{"s":50,"a":32,"key":"50:32","ar":"هَـٰذَا مَا تُوعَدُونَ لِكُلِّ أَوَّابٍ حَفِيظٍ","en":"[It will be said], \"This is what you were promised - for every returner [to Allāh] and keeper [of His covenant].","tr":"Hatha ma tooAAadoona likulliawwabin hafeeth","juz":26,"page":519},{"s":50,"a":33,"key":"50:33","ar":"مَّنْ خَشِىَ ٱلرَّحْمَـٰنَ بِٱلْغَيْبِ وَجَآءَ بِقَلْبٍ مُّنِيبٍ","en":"Who feared the Most Merciful in the unseen and came with a heart returning [in repentance].","tr":"Man khashiya arrahmanabilghaybi wajaa biqalbin muneeb","juz":26,"page":519},{"s":50,"a":34,"key":"50:34","ar":"ٱدْخُلُوهَا بِسَلَـٰمٍ ۖ ذَٰلِكَ يَوْمُ ٱلْخُلُودِ","en":"Enter it in peace. This is the Day of Eternity.\"","tr":"Odkhulooha bisalamin thalikayawmu alkhulood","juz":26,"page":519},{"s":50,"a":35,"key":"50:35","ar":"لَهُم مَّا يَشَآءُونَ فِيهَا وَلَدَيْنَا مَزِيدٌ","en":"They will have whatever they wish therein, and with Us is more.","tr":"Lahum ma yashaoona feehawaladayna mazeed","juz":26,"page":519},{"s":50,"a":36,"key":"50:36","ar":"وَكَمْ أَهْلَكْنَا قَبْلَهُم مِّن قَرْنٍ هُمْ أَشَدُّ مِنْهُم بَطْشًا فَنَقَّبُوا۟ فِى ٱلْبِلَـٰدِ هَلْ مِن مَّحِيصٍ","en":"And how many a generation before them did We destroy who were greater than them in [striking] power and had explored throughout the lands. Is there any place of escape?","tr":"Wakam ahlakna qablahum min qarnin humashaddu minhum batshan fanaqqaboo fee albiladi halmin mahees","juz":26,"page":520},{"s":50,"a":37,"key":"50:37","ar":"إِنَّ فِى ذَٰلِكَ لَذِكْرَىٰ لِمَن كَانَ لَهُۥ قَلْبٌ أَوْ أَلْقَى ٱلسَّمْعَ وَهُوَ شَهِيدٌ","en":"Indeed in that is a reminder for whoever has a heart or who listens while he is present [in mind].","tr":"Inna fee thalika lathikraliman kana lahu qalbun aw alqa assamAAawahuwa shaheed","juz":26,"page":520},{"s":50,"a":38,"key":"50:38","ar":"وَلَقَدْ خَلَقْنَا ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ وَمَا بَيْنَهُمَا فِى سِتَّةِ أَيَّامٍ وَمَا مَسَّنَا مِن لُّغُوبٍ","en":"And We did certainly create the heavens and earth and what is between them in six days, and there touched Us no weariness.","tr":"Walaqad khalaqna assamawatiwal-arda wama baynahuma fee sittatiayyamin wama massana min lughoob","juz":26,"page":520},{"s":50,"a":39,"key":"50:39","ar":"فَٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَسَبِّحْ بِحَمْدِ رَبِّكَ قَبْلَ طُلُوعِ ٱلشَّمْسِ وَقَبْلَ ٱلْغُرُوبِ","en":"So be patient, [O Muḥammad], over what they say and exalt [Allāh] with praise of your Lord before the rising of the sun and before its setting,","tr":"Fasbir AAala mayaqooloona wasabbih bihamdi rabbika qabla tulooAAiashshamsi waqabla alghuroob","juz":26,"page":520},{"s":50,"a":40,"key":"50:40","ar":"وَمِنَ ٱلَّيْلِ فَسَبِّحْهُ وَأَدْبَـٰرَ ٱلسُّجُودِ","en":"And [in part] of the night exalt Him and after prostration [i.e., prayer].","tr":"Wamina allayli fasabbihhu waadbaraassujood","juz":26,"page":520},{"s":50,"a":41,"key":"50:41","ar":"وَٱسْتَمِعْ يَوْمَ يُنَادِ ٱلْمُنَادِ مِن مَّكَانٍ قَرِيبٍ","en":"And listen on the Day when the Caller1 will call out from a place that is near -","tr":"WastamiAA yawma yunadi almunadimin makanin qareeb","juz":26,"page":520},{"s":50,"a":42,"key":"50:42","ar":"يَوْمَ يَسْمَعُونَ ٱلصَّيْحَةَ بِٱلْحَقِّ ۚ ذَٰلِكَ يَوْمُ ٱلْخُرُوجِ","en":"The Day they will hear the blast [of the Horn] in truth. That is the Day of Emergence [from the graves].","tr":"Yawma yasmaAAoona assayhatabilhaqqi thalika yawmu alkhurooj","juz":26,"page":520},{"s":50,"a":43,"key":"50:43","ar":"إِنَّا نَحْنُ نُحْىِۦ وَنُمِيتُ وَإِلَيْنَا ٱلْمَصِيرُ","en":"Indeed, it is We who give life and cause death, and to Us is the destination","tr":"Inna nahnu nuhyeewanumeetu wa-ilayna almaseer","juz":26,"page":520},{"s":50,"a":44,"key":"50:44","ar":"يَوْمَ تَشَقَّقُ ٱلْأَرْضُ عَنْهُمْ سِرَاعًا ۚ ذَٰلِكَ حَشْرٌ عَلَيْنَا يَسِيرٌ","en":"On the Day the earth breaks away from them [and they emerge] rapidly; that is a gathering easy for Us.","tr":"Yawma tashaqqaqu al-ardu AAanhum siraAAanthalika hashrun AAalayna yaseer","juz":26,"page":520},{"s":50,"a":45,"key":"50:45","ar":"نَّحْنُ أَعْلَمُ بِمَا يَقُولُونَ ۖ وَمَآ أَنتَ عَلَيْهِم بِجَبَّارٍ ۖ فَذَكِّرْ بِٱلْقُرْءَانِ مَن يَخَافُ وَعِيدِ","en":"We are most knowing of what they say, and you are not over them a tyrant.1 But remind by the Qur’ān whoever fears My threat.","tr":"Nahnu aAAlamu bima yaqooloonawama anta AAalayhim bijabbarin fathakkir bilqur-animan yakhafu waAAeed","juz":26,"page":520},{"s":51,"a":1,"key":"51:1","ar":" وَٱلذَّٰرِيَـٰتِ ذَرْوًا","en":"By the [winds] scattering [dust], dispersing [it]","tr":"Waththariyati tharwa","juz":26,"page":520},{"s":51,"a":2,"key":"51:2","ar":"فَٱلْحَـٰمِلَـٰتِ وِقْرًا","en":"And the [clouds] carrying a load [of water]","tr":"Falhamilati wiqra","juz":26,"page":520},{"s":51,"a":3,"key":"51:3","ar":"فَٱلْجَـٰرِيَـٰتِ يُسْرًا","en":"And the ships sailing with ease","tr":"Faljariyati yusra","juz":26,"page":520},{"s":51,"a":4,"key":"51:4","ar":"فَٱلْمُقَسِّمَـٰتِ أَمْرًا","en":"And the [angels] apportioning [each] matter,","tr":"Falmuqassimati amra","juz":26,"page":520},{"s":51,"a":5,"key":"51:5","ar":"إِنَّمَا تُوعَدُونَ لَصَادِقٌ","en":"Indeed, what you are promised is true.","tr":"Innama tooAAadoona lasadiq","juz":26,"page":520},{"s":51,"a":6,"key":"51:6","ar":"وَإِنَّ ٱلدِّينَ لَوَٰقِعٌ","en":"And indeed, the recompense is to occur.","tr":"Wa-inna addeena lawaqiAA","juz":26,"page":520},{"s":51,"a":7,"key":"51:7","ar":"وَٱلسَّمَآءِ ذَاتِ ٱلْحُبُكِ","en":"By the heaven containing pathways,1","tr":"Wassama-i thati alhubuk","juz":26,"page":521},{"s":51,"a":8,"key":"51:8","ar":"إِنَّكُمْ لَفِى قَوْلٍ مُّخْتَلِفٍ","en":"Indeed, you are in differing speech.1","tr":"Innakum lafee qawlin mukhtalif","juz":26,"page":521},{"s":51,"a":9,"key":"51:9","ar":"يُؤْفَكُ عَنْهُ مَنْ أُفِكَ","en":"Deluded away from it [i.e., the Qur’ān] is he who is deluded.","tr":"Yu/faku AAanhu man ofik","juz":26,"page":521},{"s":51,"a":10,"key":"51:10","ar":"قُتِلَ ٱلْخَرَّٰصُونَ","en":"Destroyed are the misinformers1","tr":"Qutila alkharrasoon","juz":26,"page":521},{"s":51,"a":11,"key":"51:11","ar":"ٱلَّذِينَ هُمْ فِى غَمْرَةٍ سَاهُونَ","en":"Who are within a flood [of confusion] and heedless.","tr":"Allatheena hum fee ghamratin sahoon","juz":26,"page":521},{"s":51,"a":12,"key":"51:12","ar":"يَسْـَٔلُونَ أَيَّانَ يَوْمُ ٱلدِّينِ","en":"They ask, \"When is the Day of Recompense?\"","tr":"Yas-aloona ayyana yawmu addeen","juz":26,"page":521},{"s":51,"a":13,"key":"51:13","ar":"يَوْمَ هُمْ عَلَى ٱلنَّارِ يُفْتَنُونَ","en":"[It is] the Day they will be tormented over the Fire.","tr":"Yawma hum AAala annariyuftanoon","juz":26,"page":521},{"s":51,"a":14,"key":"51:14","ar":"ذُوقُوا۟ فِتْنَتَكُمْ هَـٰذَا ٱلَّذِى كُنتُم بِهِۦ تَسْتَعْجِلُونَ","en":"[And will be told], \"Taste your torment. This is that for which you were impatient.\"","tr":"Thooqoo fitnatakum hatha allatheekuntum bihi tastaAAjiloon","juz":26,"page":521},{"s":51,"a":15,"key":"51:15","ar":"إِنَّ ٱلْمُتَّقِينَ فِى جَنَّـٰتٍ وَعُيُونٍ","en":"Indeed, the righteous will be among gardens and springs,","tr":"Inna almuttaqeena fee jannatinwaAAuyoon","juz":26,"page":521},{"s":51,"a":16,"key":"51:16","ar":"ءَاخِذِينَ مَآ ءَاتَىٰهُمْ رَبُّهُمْ ۚ إِنَّهُمْ كَانُوا۟ قَبْلَ ذَٰلِكَ مُحْسِنِينَ","en":"Accepting what their Lord has given them. Indeed, they were before that doers of good.","tr":"Akhitheena ma atahumrabbuhum innahum kanoo qabla thalika muhsineen","juz":26,"page":521},{"s":51,"a":17,"key":"51:17","ar":"كَانُوا۟ قَلِيلًا مِّنَ ٱلَّيْلِ مَا يَهْجَعُونَ","en":"They used to sleep but little of the night,1","tr":"Kanoo qaleelan mina allayli mayahjaAAoon","juz":26,"page":521},{"s":51,"a":18,"key":"51:18","ar":"وَبِٱلْأَسْحَارِ هُمْ يَسْتَغْفِرُونَ","en":"And in the hours before dawn they would ask forgiveness,","tr":"Wabil-ashari humyastaghfiroon","juz":26,"page":521},{"s":51,"a":19,"key":"51:19","ar":"وَفِىٓ أَمْوَٰلِهِمْ حَقٌّ لِّلسَّآئِلِ وَٱلْمَحْرُومِ","en":"And from their properties was [given] the right of the [needy] petitioner and the deprived.","tr":"Wafee amwalihim haqqun lissa-iliwalmahroom","juz":26,"page":521},{"s":51,"a":20,"key":"51:20","ar":"وَفِى ٱلْأَرْضِ ءَايَـٰتٌ لِّلْمُوقِنِينَ","en":"And on the earth are signs for the certain [in faith]","tr":"Wafee al-ardi ayatunlilmooqineen","juz":26,"page":521},{"s":51,"a":21,"key":"51:21","ar":"وَفِىٓ أَنفُسِكُمْ ۚ أَفَلَا تُبْصِرُونَ","en":"And in yourselves. Then will you not see?","tr":"Wafee anfusikum afala tubsiroon","juz":26,"page":521},{"s":51,"a":22,"key":"51:22","ar":"وَفِى ٱلسَّمَآءِ رِزْقُكُمْ وَمَا تُوعَدُونَ","en":"And in the heaven is your provision and whatever you are promised.","tr":"Wafee assama-i rizqukum wamatooAAadoon","juz":26,"page":521},{"s":51,"a":23,"key":"51:23","ar":"فَوَرَبِّ ٱلسَّمَآءِ وَٱلْأَرْضِ إِنَّهُۥ لَحَقٌّ مِّثْلَ مَآ أَنَّكُمْ تَنطِقُونَ","en":"Then by the Lord of the heaven and earth, indeed, it is truth - just as [sure as] it is that you are speaking.","tr":"Fawarabbi assama-i wal-ardiinnahu lahaqqun mithla ma annakum tantiqoon","juz":26,"page":521},{"s":51,"a":24,"key":"51:24","ar":"هَلْ أَتَىٰكَ حَدِيثُ ضَيْفِ إِبْرَٰهِيمَ ٱلْمُكْرَمِينَ","en":"Has there reached you the story of the honored guests of Abraham?1 -","tr":"Hal ataka hadeethu dayfiibraheema almukrameen","juz":26,"page":521},{"s":51,"a":25,"key":"51:25","ar":"إِذْ دَخَلُوا۟ عَلَيْهِ فَقَالُوا۟ سَلَـٰمًا ۖ قَالَ سَلَـٰمٌ قَوْمٌ مُّنكَرُونَ","en":"When they entered upon him and said, \"[We greet you with] peace.\" He answered, \"[And upon you] peace; [you are] a people unknown.\"","tr":"Ith dakhaloo AAalayhi faqaloosalaman qala salamun qawmun munkaroon","juz":26,"page":521},{"s":51,"a":26,"key":"51:26","ar":"فَرَاغَ إِلَىٰٓ أَهْلِهِۦ فَجَآءَ بِعِجْلٍ سَمِينٍ","en":"Then he went to his family and came with a fat [roasted] calf.","tr":"Faragha ila ahlihi fajaabiAAijlin sameen","juz":26,"page":521},{"s":51,"a":27,"key":"51:27","ar":"فَقَرَّبَهُۥٓ إِلَيْهِمْ قَالَ أَلَا تَأْكُلُونَ","en":"And placed it near them; he said, \"Will you not eat?\"","tr":"Faqarrabahu ilayhim qala alata/kuloon","juz":26,"page":521},{"s":51,"a":28,"key":"51:28","ar":"فَأَوْجَسَ مِنْهُمْ خِيفَةً ۖ قَالُوا۟ لَا تَخَفْ ۖ وَبَشَّرُوهُ بِغُلَـٰمٍ عَلِيمٍ","en":"And he felt from them apprehension.1 They said, \"Fear not,\" and gave him good tidings of a learned boy.","tr":"Faawjasa minhum kheefatan qaloo latakhaf wabashsharoohu bighulamin AAaleem","juz":26,"page":521},{"s":51,"a":29,"key":"51:29","ar":"فَأَقْبَلَتِ ٱمْرَأَتُهُۥ فِى صَرَّةٍ فَصَكَّتْ وَجْهَهَا وَقَالَتْ عَجُوزٌ عَقِيمٌ","en":"And his wife approached with a cry [of alarm] and struck her face and said, \"[I am] a barren old woman!\"","tr":"Faaqbalati imraatuhu fee sarratin fasakkatwajhaha waqalat AAajoozun AAaqeem","juz":26,"page":521},{"s":51,"a":30,"key":"51:30","ar":"قَالُوا۟ كَذَٰلِكِ قَالَ رَبُّكِ ۖ إِنَّهُۥ هُوَ ٱلْحَكِيمُ ٱلْعَلِيمُ","en":"They said, \"Thus has said your Lord; indeed, He is the Wise, the Knowing.\"","tr":"Qaloo kathaliki qalarabbuki innahu huwa alhakeemu alAAaleem","juz":26,"page":521},{"s":51,"a":31,"key":"51:31","ar":"۞ قَالَ فَمَا خَطْبُكُمْ أَيُّهَا ٱلْمُرْسَلُونَ","en":"[Abraham] said, \"Then what is your business [here], O messengers?\"","tr":"Qala fama khatbukumayyuha almursaloon","juz":27,"page":522},{"s":51,"a":32,"key":"51:32","ar":"قَالُوٓا۟ إِنَّآ أُرْسِلْنَآ إِلَىٰ قَوْمٍ مُّجْرِمِينَ","en":"They said, \"Indeed, we have been sent to a people of criminals1","tr":"Qaloo inna orsilna ilaqawmin mujrimeen","juz":27,"page":522},{"s":51,"a":33,"key":"51:33","ar":"لِنُرْسِلَ عَلَيْهِمْ حِجَارَةً مِّن طِينٍ","en":"To send down upon them stones of clay,","tr":"Linursila AAalayhim hijaratanmin teen","juz":27,"page":522},{"s":51,"a":34,"key":"51:34","ar":"مُّسَوَّمَةً عِندَ رَبِّكَ لِلْمُسْرِفِينَ","en":"Marked in the presence of your Lord for the transgressors.\"","tr":"Musawwamatan AAinda rabbika lilmusrifeen","juz":27,"page":522},{"s":51,"a":35,"key":"51:35","ar":"فَأَخْرَجْنَا مَن كَانَ فِيهَا مِنَ ٱلْمُؤْمِنِينَ","en":"So We brought out whoever was in them [i.e., the cities] of the believers.","tr":"Faakhrajna man kana feehamina almu/mineen","juz":27,"page":522},{"s":51,"a":36,"key":"51:36","ar":"فَمَا وَجَدْنَا فِيهَا غَيْرَ بَيْتٍ مِّنَ ٱلْمُسْلِمِينَ","en":"And We found not within them other than a [single] house of Muslims.1","tr":"Fama wajadna feehaghayra baytin mina almuslimeen","juz":27,"page":522},{"s":51,"a":37,"key":"51:37","ar":"وَتَرَكْنَا فِيهَآ ءَايَةً لِّلَّذِينَ يَخَافُونَ ٱلْعَذَابَ ٱلْأَلِيمَ","en":"And We left therein a sign for those who fear the painful punishment.","tr":"Watarakna feeha ayatanlillatheena yakhafoona alAAathaba al-aleem","juz":27,"page":522},{"s":51,"a":38,"key":"51:38","ar":"وَفِى مُوسَىٰٓ إِذْ أَرْسَلْنَـٰهُ إِلَىٰ فِرْعَوْنَ بِسُلْطَـٰنٍ مُّبِينٍ","en":"And in Moses [was a sign], when We sent him to Pharaoh with clear authority.1","tr":"Wafee moosa ith arsanahuila firAAawna bisultanin mubeen","juz":27,"page":522},{"s":51,"a":39,"key":"51:39","ar":"فَتَوَلَّىٰ بِرُكْنِهِۦ وَقَالَ سَـٰحِرٌ أَوْ مَجْنُونٌ","en":"But he turned away with his supporters and said, \"A magician or a madman.\"","tr":"Fatawalla biruknihi waqala sahirunaw majnoon","juz":27,"page":522},{"s":51,"a":40,"key":"51:40","ar":"فَأَخَذْنَـٰهُ وَجُنُودَهُۥ فَنَبَذْنَـٰهُمْ فِى ٱلْيَمِّ وَهُوَ مُلِيمٌ","en":"So We took him and his soldiers and cast them into the sea, and he was blameworthy.","tr":"Faakhathnahu wajunoodahufanabathnahum fee alyammi wahuwa muleem","juz":27,"page":522},{"s":51,"a":41,"key":"51:41","ar":"وَفِى عَادٍ إِذْ أَرْسَلْنَا عَلَيْهِمُ ٱلرِّيحَ ٱلْعَقِيمَ","en":"And in ʿAad [was a sign], when We sent against them the barren wind.1","tr":"Wafee AAadin ith arsalnaAAalayhimu arreeha alAAaqeem","juz":27,"page":522},{"s":51,"a":42,"key":"51:42","ar":"مَا تَذَرُ مِن شَىْءٍ أَتَتْ عَلَيْهِ إِلَّا جَعَلَتْهُ كَٱلرَّمِيمِ","en":"It left nothing of what it came upon but that it made it like disintegrated ruins.","tr":"Ma tatharu min shay-in atatAAalayhi illa jaAAalat-hu karrameem","juz":27,"page":522},{"s":51,"a":43,"key":"51:43","ar":"وَفِى ثَمُودَ إِذْ قِيلَ لَهُمْ تَمَتَّعُوا۟ حَتَّىٰ حِينٍ","en":"And in Thamūd, when it was said to them, \"Enjoy yourselves for a time.\"","tr":"Wafee thamooda ith qeela lahumtamattaAAoo hatta heen","juz":27,"page":522},{"s":51,"a":44,"key":"51:44","ar":"فَعَتَوْا۟ عَنْ أَمْرِ رَبِّهِمْ فَأَخَذَتْهُمُ ٱلصَّـٰعِقَةُ وَهُمْ يَنظُرُونَ","en":"But they were insolent toward the command of their Lord, so the thunderbolt seized them while they were looking on.","tr":"FaAAataw AAan amri rabbihim faakhathat-humuassaAAiqatu wahum yanthuroon","juz":27,"page":522},{"s":51,"a":45,"key":"51:45","ar":"فَمَا ٱسْتَطَـٰعُوا۟ مِن قِيَامٍ وَمَا كَانُوا۟ مُنتَصِرِينَ","en":"And they were unable to arise, nor could they defend themselves.","tr":"Fama istataAAoo min qiyaminwama kanoo muntasireen","juz":27,"page":522},{"s":51,"a":46,"key":"51:46","ar":"وَقَوْمَ نُوحٍ مِّن قَبْلُ ۖ إِنَّهُمْ كَانُوا۟ قَوْمًا فَـٰسِقِينَ","en":"And [We destroyed] the people of Noah before; indeed, they were a people defiantly disobedient.","tr":"Waqawma noohin min qablu innahum kanooqawman fasiqeen","juz":27,"page":522},{"s":51,"a":47,"key":"51:47","ar":"وَٱلسَّمَآءَ بَنَيْنَـٰهَا بِأَيْي۟دٍ وَإِنَّا لَمُوسِعُونَ","en":"And the heaven We constructed with strength,1 and indeed, We are [its] expander.","tr":"Wassamaa banaynahabi-aydin wa-inna lamoosiAAoon","juz":27,"page":522},{"s":51,"a":48,"key":"51:48","ar":"وَٱلْأَرْضَ فَرَشْنَـٰهَا فَنِعْمَ ٱلْمَـٰهِدُونَ","en":"And the earth We have spread out, and excellent is the preparer.","tr":"Wal-arda farashnahafaniAAma almahidoon","juz":27,"page":522},{"s":51,"a":49,"key":"51:49","ar":"وَمِن كُلِّ شَىْءٍ خَلَقْنَا زَوْجَيْنِ لَعَلَّكُمْ تَذَكَّرُونَ","en":"And of all things We created two mates [i.e., counterparts]; perhaps you will remember.","tr":"Wamin kulli shay-in khalaqna zawjaynilaAAallakum tathakkaroon","juz":27,"page":522},{"s":51,"a":50,"key":"51:50","ar":"فَفِرُّوٓا۟ إِلَى ٱللَّهِ ۖ إِنِّى لَكُم مِّنْهُ نَذِيرٌ مُّبِينٌ","en":"So flee to Allāh.1 Indeed, I am to you from Him a clear warner.","tr":"Fafirroo ila Allahi inneelakum minhu natheerun mubeen","juz":27,"page":522},{"s":51,"a":51,"key":"51:51","ar":"وَلَا تَجْعَلُوا۟ مَعَ ٱللَّهِ إِلَـٰهًا ءَاخَرَ ۖ إِنِّى لَكُم مِّنْهُ نَذِيرٌ مُّبِينٌ","en":"And do not make [as equal] with Allāh another deity. Indeed, I am to you from Him a clear warner.","tr":"Wala tajAAaloo maAAa Allahi ilahanakhara innee lakum minhu natheerun mubeen","juz":27,"page":522},{"s":51,"a":52,"key":"51:52","ar":"كَذَٰلِكَ مَآ أَتَى ٱلَّذِينَ مِن قَبْلِهِم مِّن رَّسُولٍ إِلَّا قَالُوا۟ سَاحِرٌ أَوْ مَجْنُونٌ","en":"Similarly, there came not to those before them any messenger except that they said, \"A magician or a madman.\"","tr":"Kathalika ma ata allatheenamin qablihim min rasoolin illa qaloo sahirunaw majnoon","juz":27,"page":523},{"s":51,"a":53,"key":"51:53","ar":"أَتَوَاصَوْا۟ بِهِۦ ۚ بَلْ هُمْ قَوْمٌ طَاغُونَ","en":"Did they suggest it to them?1 Rather, they [themselves] are a transgressing people.","tr":"Atawasaw bihi bal hum qawmun taghoon","juz":27,"page":523},{"s":51,"a":54,"key":"51:54","ar":"فَتَوَلَّ عَنْهُمْ فَمَآ أَنتَ بِمَلُومٍ","en":"So leave them, [O Muḥammad], for you are not to be blamed.","tr":"Fatawalla AAanhum fama anta bimaloom","juz":27,"page":523},{"s":51,"a":55,"key":"51:55","ar":"وَذَكِّرْ فَإِنَّ ٱلذِّكْرَىٰ تَنفَعُ ٱلْمُؤْمِنِينَ","en":"And remind, for indeed, the reminder benefits the believers.","tr":"Wathakkir fa-inna aththikratanfaAAu almu/mineen","juz":27,"page":523},{"s":51,"a":56,"key":"51:56","ar":"وَمَا خَلَقْتُ ٱلْجِنَّ وَٱلْإِنسَ إِلَّا لِيَعْبُدُونِ","en":"And I did not create the jinn and mankind except to worship Me.","tr":"Wama khalaqtu aljinna wal-insailla liyaAAbudoon","juz":27,"page":523},{"s":51,"a":57,"key":"51:57","ar":"مَآ أُرِيدُ مِنْهُم مِّن رِّزْقٍ وَمَآ أُرِيدُ أَن يُطْعِمُونِ","en":"I do not want from them any provision, nor do I want them to feed Me.","tr":"Ma oreedu minhum min rizqin wamaoreedu an yutAAimoon","juz":27,"page":523},{"s":51,"a":58,"key":"51:58","ar":"إِنَّ ٱللَّهَ هُوَ ٱلرَّزَّاقُ ذُو ٱلْقُوَّةِ ٱلْمَتِينُ","en":"Indeed, it is Allāh who is the [continual] Provider,1 the firm possessor of strength.","tr":"Inna Allaha huwa arrazzaquthoo alquwwati almateen","juz":27,"page":523},{"s":51,"a":59,"key":"51:59","ar":"فَإِنَّ لِلَّذِينَ ظَلَمُوا۟ ذَنُوبًا مِّثْلَ ذَنُوبِ أَصْحَـٰبِهِمْ فَلَا يَسْتَعْجِلُونِ","en":"And indeed, for those who have wronged is a portion [of punishment] like the portion of their companions [i.e., predecessors], so let them not impatiently urge Me.","tr":"Fa-inna lillatheena thalamoothanooban mithla thanoobi as-habihimfala yastaAAjiloon","juz":27,"page":523},{"s":51,"a":60,"key":"51:60","ar":"فَوَيْلٌ لِّلَّذِينَ كَفَرُوا۟ مِن يَوْمِهِمُ ٱلَّذِى يُوعَدُونَ","en":"And woe to those who have disbelieved from their Day which they are promised.","tr":"Fawaylun lillatheena kafaroo minyawmihimu allathee yooAAadoon","juz":27,"page":523},{"s":52,"a":1,"key":"52:1","ar":" وَٱلطُّورِ","en":"By the mount","tr":"Wattoor","juz":27,"page":523},{"s":52,"a":2,"key":"52:2","ar":"وَكِتَـٰبٍ مَّسْطُورٍ","en":"And [by] a Book inscribed1","tr":"Wakitabin mastoor","juz":27,"page":523},{"s":52,"a":3,"key":"52:3","ar":"فِى رَقٍّ مَّنشُورٍ","en":"In parchment spread open","tr":"Fee raqqin manshoor","juz":27,"page":523},{"s":52,"a":4,"key":"52:4","ar":"وَٱلْبَيْتِ ٱلْمَعْمُورِ","en":"And [by] the frequented House1","tr":"Walbayti almaAAmoor","juz":27,"page":523},{"s":52,"a":5,"key":"52:5","ar":"وَٱلسَّقْفِ ٱلْمَرْفُوعِ","en":"And [by] the ceiling [i.e., heaven] raised high","tr":"Wassaqfi almarfooAA","juz":27,"page":523},{"s":52,"a":6,"key":"52:6","ar":"وَٱلْبَحْرِ ٱلْمَسْجُورِ","en":"And [by] the sea set on fire,1","tr":"Walbahri almasjoor","juz":27,"page":523},{"s":52,"a":7,"key":"52:7","ar":"إِنَّ عَذَابَ رَبِّكَ لَوَٰقِعٌ","en":"Indeed, the punishment of your Lord will occur.","tr":"Inna AAathaba rabbika lawaqiAA","juz":27,"page":523},{"s":52,"a":8,"key":"52:8","ar":"مَّا لَهُۥ مِن دَافِعٍ","en":"Of it there is no preventer.","tr":"Ma lahu min dafiAA","juz":27,"page":523},{"s":52,"a":9,"key":"52:9","ar":"يَوْمَ تَمُورُ ٱلسَّمَآءُ مَوْرًا","en":"On the Day the heaven will sway with circular motion","tr":"Yawma tamooru assamao mawra","juz":27,"page":523},{"s":52,"a":10,"key":"52:10","ar":"وَتَسِيرُ ٱلْجِبَالُ سَيْرًا","en":"And the mountains will pass on, departing1 -","tr":"Wataseeru aljibalu sayra","juz":27,"page":523},{"s":52,"a":11,"key":"52:11","ar":"فَوَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Then woe, that Day, to the deniers,","tr":"Fawaylun yawma-ithin lilmukaththibeen","juz":27,"page":523},{"s":52,"a":12,"key":"52:12","ar":"ٱلَّذِينَ هُمْ فِى خَوْضٍ يَلْعَبُونَ","en":"Who are in [empty] discourse amusing themselves.","tr":"Allatheena hum fee khawdinyalAAaboon","juz":27,"page":523},{"s":52,"a":13,"key":"52:13","ar":"يَوْمَ يُدَعُّونَ إِلَىٰ نَارِ جَهَنَّمَ دَعًّا","en":"The Day they are thrust toward the fire of Hell with a [violent] thrust, [its angels will say],","tr":"Yawma yudaAAAAoona ila narijahannama daAAAAa","juz":27,"page":523},{"s":52,"a":14,"key":"52:14","ar":"هَـٰذِهِ ٱلنَّارُ ٱلَّتِى كُنتُم بِهَا تُكَذِّبُونَ","en":"\"This is the Fire which you used to deny.","tr":"Hathihi annaru allateekuntum biha tukaththiboon","juz":27,"page":523},{"s":52,"a":15,"key":"52:15","ar":"أَفَسِحْرٌ هَـٰذَآ أَمْ أَنتُمْ لَا تُبْصِرُونَ","en":"Then is this magic, or do you not see?","tr":"Afasihrun hatha am antum latubsiroon","juz":27,"page":524},{"s":52,"a":16,"key":"52:16","ar":"ٱصْلَوْهَا فَٱصْبِرُوٓا۟ أَوْ لَا تَصْبِرُوا۟ سَوَآءٌ عَلَيْكُمْ ۖ إِنَّمَا تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَ","en":"[Enter to] burn therein; then be patient or impatient - it is all the same for you. You are only being recompensed [for] what you used to do.\"","tr":"Islawha fasbirooaw la tasbiroo sawaon AAalaykum innamatujzawna ma kuntum taAAmaloon","juz":27,"page":524},{"s":52,"a":17,"key":"52:17","ar":"إِنَّ ٱلْمُتَّقِينَ فِى جَنَّـٰتٍ وَنَعِيمٍ","en":"Indeed, the righteous will be in gardens and pleasure,","tr":"Inna almuttaqeena fee jannatinwanaAAeem","juz":27,"page":524},{"s":52,"a":18,"key":"52:18","ar":"فَـٰكِهِينَ بِمَآ ءَاتَىٰهُمْ رَبُّهُمْ وَوَقَىٰهُمْ رَبُّهُمْ عَذَابَ ٱلْجَحِيمِ","en":"Enjoying what their Lord has given them, and their Lord protected them from the punishment of Hellfire.","tr":"Fakiheena bima atahumrabbuhum wawaqahum rabbuhum AAathaba aljaheem","juz":27,"page":524},{"s":52,"a":19,"key":"52:19","ar":"كُلُوا۟ وَٱشْرَبُوا۟ هَنِيٓـًٔۢا بِمَا كُنتُمْ تَعْمَلُونَ","en":"[They will be told], \"Eat and drink in satisfaction for what you used to do.\"","tr":"Kuloo washraboo hanee-an bimakuntum taAAmaloon","juz":27,"page":524},{"s":52,"a":20,"key":"52:20","ar":"مُتَّكِـِٔينَ عَلَىٰ سُرُرٍ مَّصْفُوفَةٍ ۖ وَزَوَّجْنَـٰهُم بِحُورٍ عِينٍ","en":"They will be reclining on thrones lined up, and We will marry them to fair women with large, [beautiful] eyes.","tr":"Muttaki-eena AAala sururin masfoofatinwazawwajnahum bihoorin AAeen","juz":27,"page":524},{"s":52,"a":21,"key":"52:21","ar":"وَٱلَّذِينَ ءَامَنُوا۟ وَٱتَّبَعَتْهُمْ ذُرِّيَّتُهُم بِإِيمَـٰنٍ أَلْحَقْنَا بِهِمْ ذُرِّيَّتَهُمْ وَمَآ أَلَتْنَـٰهُم مِّنْ عَمَلِهِم مِّن شَىْءٍ ۚ كُلُّ ٱمْرِئٍۭ بِمَا كَسَبَ رَهِينٌ","en":"And those who believed and whose descendants followed them in faith - We will join with them their descendants, and We will not deprive them of anything of their deeds.1 Every person, for what he earned, is retained.2","tr":"Wallatheena amanoo wattabaAAat-humthurriyyatuhum bi-eemanin alhaqnabihim thurriyyatahum wama alatnahum minAAamalihim min shay-in kullu imri-in bima kasaba raheen","juz":27,"page":524},{"s":52,"a":22,"key":"52:22","ar":"وَأَمْدَدْنَـٰهُم بِفَـٰكِهَةٍ وَلَحْمٍ مِّمَّا يَشْتَهُونَ","en":"And We will provide them with fruit and meat from whatever they desire.","tr":"Waamdadnahum bifakihatin walahminmimma yashtahoon","juz":27,"page":524},{"s":52,"a":23,"key":"52:23","ar":"يَتَنَـٰزَعُونَ فِيهَا كَأْسًا لَّا لَغْوٌ فِيهَا وَلَا تَأْثِيمٌ","en":"They will exchange with one another a cup [of wine] wherein [results] no ill speech or commission of sin.","tr":"YatanazaAAoona feeha ka/san lalaghwun feeha wala ta/theem","juz":27,"page":524},{"s":52,"a":24,"key":"52:24","ar":"۞ وَيَطُوفُ عَلَيْهِمْ غِلْمَانٌ لَّهُمْ كَأَنَّهُمْ لُؤْلُؤٌ مَّكْنُونٌ","en":"There will circulate among them [servant] boys [especially] for them, as if they were pearls well-protected.","tr":"Wayatoofu AAalayhim ghilmanunlahum kaannahum lu/luon maknoon","juz":27,"page":524},{"s":52,"a":25,"key":"52:25","ar":"وَأَقْبَلَ بَعْضُهُمْ عَلَىٰ بَعْضٍ يَتَسَآءَلُونَ","en":"And they will approach one another, inquiring of each other.","tr":"Waaqbala baAAduhum AAala baAAdinyatasaaloon","juz":27,"page":524},{"s":52,"a":26,"key":"52:26","ar":"قَالُوٓا۟ إِنَّا كُنَّا قَبْلُ فِىٓ أَهْلِنَا مُشْفِقِينَ","en":"They will say, \"Indeed, we were previously among our people fearful [of displeasing Allāh].","tr":"Qaloo inna kunna qablufee ahlina mushfiqeen","juz":27,"page":524},{"s":52,"a":27,"key":"52:27","ar":"فَمَنَّ ٱللَّهُ عَلَيْنَا وَوَقَىٰنَا عَذَابَ ٱلسَّمُومِ","en":"So Allāh conferred favor upon us and protected us from the punishment of the Scorching Fire.","tr":"Famanna Allahu AAalayna wawaqanaAAathaba assamoom","juz":27,"page":524},{"s":52,"a":28,"key":"52:28","ar":"إِنَّا كُنَّا مِن قَبْلُ نَدْعُوهُ ۖ إِنَّهُۥ هُوَ ٱلْبَرُّ ٱلرَّحِيمُ","en":"Indeed, we used to supplicate1 Him before. Indeed, it is He who is the Beneficent, the Merciful.\"","tr":"Inna kunna min qablu nadAAoohuinnahu huwa albarru arraheem","juz":27,"page":524},{"s":52,"a":29,"key":"52:29","ar":"فَذَكِّرْ فَمَآ أَنتَ بِنِعْمَتِ رَبِّكَ بِكَاهِنٍ وَلَا مَجْنُونٍ","en":"So remind, [O Muḥammad], for you are not, by the favor of your Lord, a soothsayer or a madman.","tr":"Fathakkir fama anta biniAAmatirabbika bikahin wala majnoon","juz":27,"page":524},{"s":52,"a":30,"key":"52:30","ar":"أَمْ يَقُولُونَ شَاعِرٌ نَّتَرَبَّصُ بِهِۦ رَيْبَ ٱلْمَنُونِ","en":"Or do they say [of you], \"A poet for whom we await a misfortune of time\"?1","tr":"Am yaqooloona shaAAirun natarabbasubihi rayba almanoon","juz":27,"page":524},{"s":52,"a":31,"key":"52:31","ar":"قُلْ تَرَبَّصُوا۟ فَإِنِّى مَعَكُم مِّنَ ٱلْمُتَرَبِّصِينَ","en":"Say, \"Wait, for indeed I am, with you, among the waiters.\"","tr":"Qul tarabbasoo fa-innee maAAakum minaalmutarabbiseen","juz":27,"page":524},{"s":52,"a":32,"key":"52:32","ar":"أَمْ تَأْمُرُهُمْ أَحْلَـٰمُهُم بِهَـٰذَآ ۚ أَمْ هُمْ قَوْمٌ طَاغُونَ","en":"Or do their minds1 command them to [say] this, or are they a transgressing people?","tr":"Am ta/muruhum ahlamuhum bihathaam hum qawmun taghoon","juz":27,"page":525},{"s":52,"a":33,"key":"52:33","ar":"أَمْ يَقُولُونَ تَقَوَّلَهُۥ ۚ بَل لَّا يُؤْمِنُونَ","en":"Or do they say, \"He has made it up\"? Rather, they do not believe.","tr":"Am yaqooloona taqawwalahu bal layu/minoon","juz":27,"page":525},{"s":52,"a":34,"key":"52:34","ar":"فَلْيَأْتُوا۟ بِحَدِيثٍ مِّثْلِهِۦٓ إِن كَانُوا۟ صَـٰدِقِينَ","en":"Then let them produce a statement like it, if they should be truthful.","tr":"Falya/too bihadeethin mithlihi in kanoosadiqeena","juz":27,"page":525},{"s":52,"a":35,"key":"52:35","ar":"أَمْ خُلِقُوا۟ مِنْ غَيْرِ شَىْءٍ أَمْ هُمُ ٱلْخَـٰلِقُونَ","en":"Or were they created by nothing, or were they the creators [of themselves]?","tr":"Am khuliqoo min ghayri shay-in am humu alkhaliqoon","juz":27,"page":525},{"s":52,"a":36,"key":"52:36","ar":"أَمْ خَلَقُوا۟ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ ۚ بَل لَّا يُوقِنُونَ","en":"Or did they create the heavens and the earth? Rather, they are not certain.","tr":"Am khalaqoo assamawatiwal-arda bal la yooqinoon","juz":27,"page":525},{"s":52,"a":37,"key":"52:37","ar":"أَمْ عِندَهُمْ خَزَآئِنُ رَبِّكَ أَمْ هُمُ ٱلْمُصَۣيْطِرُونَ","en":"Or have they the depositories [containing the provision] of your Lord? Or are they the controllers [of them]?","tr":"Am AAindahum khaza-inu rabbika amhumu almusaytiroon","juz":27,"page":525},{"s":52,"a":38,"key":"52:38","ar":"أَمْ لَهُمْ سُلَّمٌ يَسْتَمِعُونَ فِيهِ ۖ فَلْيَأْتِ مُسْتَمِعُهُم بِسُلْطَـٰنٍ مُّبِينٍ","en":"Or have they a stairway [into the heaven] upon which they listen? Then let their listener produce a clear authority [i.e., proof].","tr":"Am lahum sullamun yastamiAAoona feehifalya/ti mustamiAAuhum bisultanin mubeen","juz":27,"page":525},{"s":52,"a":39,"key":"52:39","ar":"أَمْ لَهُ ٱلْبَنَـٰتُ وَلَكُمُ ٱلْبَنُونَ","en":"Or has He daughters while you have sons?","tr":"Am lahu albanatu walakumu albanoon","juz":27,"page":525},{"s":52,"a":40,"key":"52:40","ar":"أَمْ تَسْـَٔلُهُمْ أَجْرًا فَهُم مِّن مَّغْرَمٍ مُّثْقَلُونَ","en":"Or do you, [O Muḥammad], ask of them a payment, so they are by debt burdened down?","tr":"Am tas-aluhum ajran fahum min maghraminmuthqaloon","juz":27,"page":525},{"s":52,"a":41,"key":"52:41","ar":"أَمْ عِندَهُمُ ٱلْغَيْبُ فَهُمْ يَكْتُبُونَ","en":"Or have they [knowledge of] the unseen, so they write [it] down?","tr":"Am AAindahumu alghaybu fahum yaktuboon","juz":27,"page":525},{"s":52,"a":42,"key":"52:42","ar":"أَمْ يُرِيدُونَ كَيْدًا ۖ فَٱلَّذِينَ كَفَرُوا۟ هُمُ ٱلْمَكِيدُونَ","en":"Or do they intend a plan? But those who disbelieve - they are the object of a plan.","tr":"Am yureedoona kaydan fallatheenakafaroo humu almakeedoon","juz":27,"page":525},{"s":52,"a":43,"key":"52:43","ar":"أَمْ لَهُمْ إِلَـٰهٌ غَيْرُ ٱللَّهِ ۚ سُبْحَـٰنَ ٱللَّهِ عَمَّا يُشْرِكُونَ","en":"Or have they a deity other than Allāh? Exalted is Allāh above whatever they associate with Him.","tr":"Am lahum ilahun ghayru Allahisubhana Allahi AAamma yushrikoon","juz":27,"page":525},{"s":52,"a":44,"key":"52:44","ar":"وَإِن يَرَوْا۟ كِسْفًا مِّنَ ٱلسَّمَآءِ سَاقِطًا يَقُولُوا۟ سَحَابٌ مَّرْكُومٌ","en":"And if they were to see a fragment from the sky falling,1 they would say, \"[It is merely] clouds heaped up.\"","tr":"Wa-in yaraw kisfan mina assama-isaqitan yaqooloo sahabun markoom","juz":27,"page":525},{"s":52,"a":45,"key":"52:45","ar":"فَذَرْهُمْ حَتَّىٰ يُلَـٰقُوا۟ يَوْمَهُمُ ٱلَّذِى فِيهِ يُصْعَقُونَ","en":"So leave them until they meet their Day in which they will be struck insensible -","tr":"Fatharhum hatta yulaqooyawmahumu allathee feehi yusAAaqoon","juz":27,"page":525},{"s":52,"a":46,"key":"52:46","ar":"يَوْمَ لَا يُغْنِى عَنْهُمْ كَيْدُهُمْ شَيْـًٔا وَلَا هُمْ يُنصَرُونَ","en":"The Day their plan will not avail them at all, nor will they be helped.","tr":"Yawma la yughnee AAanhum kayduhumshay-an wala hum yunsaroon","juz":27,"page":525},{"s":52,"a":47,"key":"52:47","ar":"وَإِنَّ لِلَّذِينَ ظَلَمُوا۟ عَذَابًا دُونَ ذَٰلِكَ وَلَـٰكِنَّ أَكْثَرَهُمْ لَا يَعْلَمُونَ","en":"And indeed, for those who have wronged is a punishment1 before that, but most of them do not know.","tr":"Wa-inna lillatheena thalamooAAathaban doona thalika walakinna aktharahumla yaAAlamoon","juz":27,"page":525},{"s":52,"a":48,"key":"52:48","ar":"وَٱصْبِرْ لِحُكْمِ رَبِّكَ فَإِنَّكَ بِأَعْيُنِنَا ۖ وَسَبِّحْ بِحَمْدِ رَبِّكَ حِينَ تَقُومُ","en":"And be patient, [O Muḥammad], for the decision of your Lord, for indeed, you are in Our eyes [i.e., sight]. And exalt [Allāh] with praise of your Lord when you arise","tr":"Wasbir lihukmi rabbikafa-innaka bi-aAAyunina wasabbih bihamdirabbika heena taqoom","juz":27,"page":525},{"s":52,"a":49,"key":"52:49","ar":"وَمِنَ ٱلَّيْلِ فَسَبِّحْهُ وَإِدْبَـٰرَ ٱلنُّجُومِ","en":"And in a part of the night exalt Him and after [the setting of] the stars.","tr":"Wamina allayli fasabbihhu wa-idbaraannujoom","juz":27,"page":525},{"s":53,"a":1,"key":"53:1","ar":" وَٱلنَّجْمِ إِذَا هَوَىٰ","en":"By the star when it descends,","tr":"Wannajmi itha hawa","juz":27,"page":526},{"s":53,"a":2,"key":"53:2","ar":"مَا ضَلَّ صَاحِبُكُمْ وَمَا غَوَىٰ","en":"Your companion [i.e., Muḥammad] has not strayed, nor has he erred,","tr":"Ma dalla sahibukum wamaghawa","juz":27,"page":526},{"s":53,"a":3,"key":"53:3","ar":"وَمَا يَنطِقُ عَنِ ٱلْهَوَىٰٓ","en":"Nor does he speak from [his own] inclination.","tr":"Wama yantiqu AAani alhawa","juz":27,"page":526},{"s":53,"a":4,"key":"53:4","ar":"إِنْ هُوَ إِلَّا وَحْىٌ يُوحَىٰ","en":"It is not but a revelation revealed,","tr":"In huwa illa wahyun yooha","juz":27,"page":526},{"s":53,"a":5,"key":"53:5","ar":"عَلَّمَهُۥ شَدِيدُ ٱلْقُوَىٰ","en":"Taught to him by one intense in strength [i.e., Gabriel] -","tr":"AAallamahu shadeedu alquwa","juz":27,"page":526},{"s":53,"a":6,"key":"53:6","ar":"ذُو مِرَّةٍ فَٱسْتَوَىٰ","en":"One of soundness.1 And he rose to [his] true form2","tr":"Thoo mirratin fastawa","juz":27,"page":526},{"s":53,"a":7,"key":"53:7","ar":"وَهُوَ بِٱلْأُفُقِ ٱلْأَعْلَىٰ","en":"While he was in the higher [part of the] horizon.1","tr":"Wahuwa bil-ofuqi al-aAAla","juz":27,"page":526},{"s":53,"a":8,"key":"53:8","ar":"ثُمَّ دَنَا فَتَدَلَّىٰ","en":"Then he approached and descended","tr":"Thumma dana fatadalla","juz":27,"page":526},{"s":53,"a":9,"key":"53:9","ar":"فَكَانَ قَابَ قَوْسَيْنِ أَوْ أَدْنَىٰ","en":"And was at a distance of two bow lengths or nearer.","tr":"Fakana qaba qawsayni aw adna","juz":27,"page":526},{"s":53,"a":10,"key":"53:10","ar":"فَأَوْحَىٰٓ إِلَىٰ عَبْدِهِۦ مَآ أَوْحَىٰ","en":"And he revealed to His Servant1 what he revealed [i.e., conveyed].","tr":"Faawha ila AAabdihi maawha","juz":27,"page":526},{"s":53,"a":11,"key":"53:11","ar":"مَا كَذَبَ ٱلْفُؤَادُ مَا رَأَىٰٓ","en":"The heart1 did not lie [about] what it saw.","tr":"Ma kathaba alfu-adu maraa","juz":27,"page":526},{"s":53,"a":12,"key":"53:12","ar":"أَفَتُمَـٰرُونَهُۥ عَلَىٰ مَا يَرَىٰ","en":"So will you dispute with him over what he saw?","tr":"Afatumaroonahu AAala mayara","juz":27,"page":526},{"s":53,"a":13,"key":"53:13","ar":"وَلَقَدْ رَءَاهُ نَزْلَةً أُخْرَىٰ","en":"And he certainly saw him in another descent1","tr":"Walaqad raahu nazlatan okhra","juz":27,"page":526},{"s":53,"a":14,"key":"53:14","ar":"عِندَ سِدْرَةِ ٱلْمُنتَهَىٰ","en":"At the Lote Tree of the Utmost Boundary -","tr":"AAinda sidrati almuntaha","juz":27,"page":526},{"s":53,"a":15,"key":"53:15","ar":"عِندَهَا جَنَّةُ ٱلْمَأْوَىٰٓ","en":"Near it is the Garden of Refuge [i.e., Paradise] -","tr":"AAindaha jannatu alma/wa","juz":27,"page":526},{"s":53,"a":16,"key":"53:16","ar":"إِذْ يَغْشَى ٱلسِّدْرَةَ مَا يَغْشَىٰ","en":"When there covered the Lote Tree that which covered [it].1","tr":"Ith yaghsha assidratama yaghsha","juz":27,"page":526},{"s":53,"a":17,"key":"53:17","ar":"مَا زَاغَ ٱلْبَصَرُ وَمَا طَغَىٰ","en":"The sight [of the Prophet (ﷺ)] did not swerve, nor did it transgress [its limit].","tr":"Ma zagha albasaru wamatagha","juz":27,"page":526},{"s":53,"a":18,"key":"53:18","ar":"لَقَدْ رَأَىٰ مِنْ ءَايَـٰتِ رَبِّهِ ٱلْكُبْرَىٰٓ","en":"He certainly saw of the greatest signs of his Lord.","tr":"Laqad raa min ayatirabbihi alkubra","juz":27,"page":526},{"s":53,"a":19,"key":"53:19","ar":"أَفَرَءَيْتُمُ ٱللَّـٰتَ وَٱلْعُزَّىٰ","en":"So have you considered al-Lāt and al-ʿUzzā?","tr":"Afaraaytumu allata walAAuzza","juz":27,"page":526},{"s":53,"a":20,"key":"53:20","ar":"وَمَنَوٰةَ ٱلثَّالِثَةَ ٱلْأُخْرَىٰٓ","en":"And Manāt, the third - the other one?1","tr":"Wamanata aththalithataal-okhra","juz":27,"page":526},{"s":53,"a":21,"key":"53:21","ar":"أَلَكُمُ ٱلذَّكَرُ وَلَهُ ٱلْأُنثَىٰ","en":"Is the male for you and for Him the female?","tr":"Alakumu aththakaru walahual-ontha","juz":27,"page":526},{"s":53,"a":22,"key":"53:22","ar":"تِلْكَ إِذًا قِسْمَةٌ ضِيزَىٰٓ","en":"That, then, is an unjust division.1","tr":"Tilka ithan qismatun deeza","juz":27,"page":526},{"s":53,"a":23,"key":"53:23","ar":"إِنْ هِىَ إِلَّآ أَسْمَآءٌ سَمَّيْتُمُوهَآ أَنتُمْ وَءَابَآؤُكُم مَّآ أَنزَلَ ٱللَّهُ بِهَا مِن سُلْطَـٰنٍ ۚ إِن يَتَّبِعُونَ إِلَّا ٱلظَّنَّ وَمَا تَهْوَى ٱلْأَنفُسُ ۖ وَلَقَدْ جَآءَهُم مِّن رَّبِّهِمُ ٱلْهُدَىٰٓ","en":"They are not but [mere] names you have named them - you and your forefathers - for which Allāh has sent down no authority. They follow not except assumption and what [their] souls desire, and there has already come to them from their Lord guidance.","tr":"In hiya illa asmaonsammaytumooha antum waabaokum maanzala Allahu biha min sultanin inyattabiAAoona illa aththanna wamatahwa al-anfusu walaqad jaahum min rabbihimu alhuda","juz":27,"page":526},{"s":53,"a":24,"key":"53:24","ar":"أَمْ لِلْإِنسَـٰنِ مَا تَمَنَّىٰ","en":"Or is there for man whatever he wishes?","tr":"Am lil-insani ma tamanna","juz":27,"page":526},{"s":53,"a":25,"key":"53:25","ar":"فَلِلَّهِ ٱلْـَٔاخِرَةُ وَٱلْأُولَىٰ","en":"Rather, to Allāh belongs the Hereafter and the first [life].","tr":"Falillahi al-akhiratu wal-oola","juz":27,"page":526},{"s":53,"a":26,"key":"53:26","ar":"۞ وَكَم مِّن مَّلَكٍ فِى ٱلسَّمَـٰوَٰتِ لَا تُغْنِى شَفَـٰعَتُهُمْ شَيْـًٔا إِلَّا مِنۢ بَعْدِ أَن يَأْذَنَ ٱللَّهُ لِمَن يَشَآءُ وَيَرْضَىٰٓ","en":"And how many angels there are in the heavens whose intercession will not avail at all except [only] after Allāh has permitted [it] to whom He wills and approves.","tr":"Wakam min malakin fee assamawatila tughnee shafaAAatuhum shay-an illa minbaAAdi an ya/thana Allahu liman yashao wayarda","juz":27,"page":526},{"s":53,"a":27,"key":"53:27","ar":"إِنَّ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْـَٔاخِرَةِ لَيُسَمُّونَ ٱلْمَلَـٰٓئِكَةَ تَسْمِيَةَ ٱلْأُنثَىٰ","en":"Indeed, those who do not believe in the Hereafter name the angels female names,","tr":"Inna allatheena la yu/minoonabil-akhirati layusammoona almala-ikatatasmiyata al-ontha","juz":27,"page":527},{"s":53,"a":28,"key":"53:28","ar":"وَمَا لَهُم بِهِۦ مِنْ عِلْمٍ ۖ إِن يَتَّبِعُونَ إِلَّا ٱلظَّنَّ ۖ وَإِنَّ ٱلظَّنَّ لَا يُغْنِى مِنَ ٱلْحَقِّ شَيْـًٔا","en":"And they have thereof no knowledge. They follow not except assumption, and indeed, assumption avails not against the truth at all.","tr":"Wama lahum bihi min AAilmin inyattabiAAoona illa aththanna wa-innaaththanna la yughnee mina alhaqqishay-a","juz":27,"page":527},{"s":53,"a":29,"key":"53:29","ar":"فَأَعْرِضْ عَن مَّن تَوَلَّىٰ عَن ذِكْرِنَا وَلَمْ يُرِدْ إِلَّا ٱلْحَيَوٰةَ ٱلدُّنْيَا","en":"So turn away from whoever turns his back on Our message and desires not except the worldly life.","tr":"FaaAArid AAan man tawalla AAanthikrina walam yurid illa alhayataaddunya","juz":27,"page":527},{"s":53,"a":30,"key":"53:30","ar":"ذَٰلِكَ مَبْلَغُهُم مِّنَ ٱلْعِلْمِ ۚ إِنَّ رَبَّكَ هُوَ أَعْلَمُ بِمَن ضَلَّ عَن سَبِيلِهِۦ وَهُوَ أَعْلَمُ بِمَنِ ٱهْتَدَىٰ","en":"That is their sum of knowledge. Indeed, your Lord is most knowing of who strays from His way, and He is most knowing of who is guided.","tr":"Thalika mablaghuhum mina alAAilmiinna rabbaka huwa aAAlamu biman dalla AAan sabeelihiwahuwa aAAlamu bimani ihtada","juz":27,"page":527},{"s":53,"a":31,"key":"53:31","ar":"وَلِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ لِيَجْزِىَ ٱلَّذِينَ أَسَـٰٓـُٔوا۟ بِمَا عَمِلُوا۟ وَيَجْزِىَ ٱلَّذِينَ أَحْسَنُوا۟ بِٱلْحُسْنَى","en":"And to Allāh belongs whatever is in the heavens and whatever is in the earth - that He may recompense those who do evil with [the penalty of] what they have done and recompense those who do good with the best [reward] -","tr":"Walillahi ma fee assamawatiwama fee al-ardi liyajziya allatheena asaoobima AAamiloo wayajziya allatheena ahsanoobilhusna","juz":27,"page":527},{"s":53,"a":32,"key":"53:32","ar":"ٱلَّذِينَ يَجْتَنِبُونَ كَبَـٰٓئِرَ ٱلْإِثْمِ وَٱلْفَوَٰحِشَ إِلَّا ٱللَّمَمَ ۚ إِنَّ رَبَّكَ وَٰسِعُ ٱلْمَغْفِرَةِ ۚ هُوَ أَعْلَمُ بِكُمْ إِذْ أَنشَأَكُم مِّنَ ٱلْأَرْضِ وَإِذْ أَنتُمْ أَجِنَّةٌ فِى بُطُونِ أُمَّهَـٰتِكُمْ ۖ فَلَا تُزَكُّوٓا۟ أَنفُسَكُمْ ۖ هُوَ أَعْلَمُ بِمَنِ ٱتَّقَىٰٓ","en":"Those who avoid the major sins and immoralities, only [committing] slight ones. Indeed, your Lord is vast in forgiveness. He was most knowing of you when He produced you from the earth and when you were fetuses in the wombs of your mothers. So do not claim yourselves to be pure; He is most knowing of who fears Him.","tr":"Allatheena yajtaniboona kaba-iraal-ithmi walfawahisha illa allamama innarabbaka wasiAAu almaghfirati huwa aAAlamu bikum ithanshaakum mina al-ardi wa-ith antum ajinnatun feebutooni ommahatikum fala tuzakkoo anfusakumhuwa aAAlamu bimani ittaqa","juz":27,"page":527},{"s":53,"a":33,"key":"53:33","ar":"أَفَرَءَيْتَ ٱلَّذِى تَوَلَّىٰ","en":"Have you seen the one who turned away","tr":"Afaraayta allathee tawalla","juz":27,"page":527},{"s":53,"a":34,"key":"53:34","ar":"وَأَعْطَىٰ قَلِيلًا وَأَكْدَىٰٓ","en":"And gave a little and [then] refrained?","tr":"WaaAAta qaleelan waakda","juz":27,"page":527},{"s":53,"a":35,"key":"53:35","ar":"أَعِندَهُۥ عِلْمُ ٱلْغَيْبِ فَهُوَ يَرَىٰٓ","en":"Does he have knowledge of the unseen, so he sees?1","tr":"aAAindahu AAilmu alghaybi fahuwa yara","juz":27,"page":527},{"s":53,"a":36,"key":"53:36","ar":"أَمْ لَمْ يُنَبَّأْ بِمَا فِى صُحُفِ مُوسَىٰ","en":"Or has he not been informed of what was in the scriptures of Moses","tr":"Am lam yunabba/ bima fee suhufimoosa","juz":27,"page":527},{"s":53,"a":37,"key":"53:37","ar":"وَإِبْرَٰهِيمَ ٱلَّذِى وَفَّىٰٓ","en":"And [of] Abraham, who fulfilled [his obligations] -","tr":"Wa-ibraheema allathee waffa","juz":27,"page":527},{"s":53,"a":38,"key":"53:38","ar":"أَلَّا تَزِرُ وَازِرَةٌ وِزْرَ أُخْرَىٰ","en":"That no bearer of burdens will bear the burden of another","tr":"Alla taziru waziratun wizraokhra","juz":27,"page":527},{"s":53,"a":39,"key":"53:39","ar":"وَأَن لَّيْسَ لِلْإِنسَـٰنِ إِلَّا مَا سَعَىٰ","en":"And that there is not for man except that [good] for which he strives","tr":"Waan laysa lil-insani illa masaAAa","juz":27,"page":527},{"s":53,"a":40,"key":"53:40","ar":"وَأَنَّ سَعْيَهُۥ سَوْفَ يُرَىٰ","en":"And that his effort is going to be seen -","tr":"Waanna saAAyahu sawfa yura","juz":27,"page":527},{"s":53,"a":41,"key":"53:41","ar":"ثُمَّ يُجْزَىٰهُ ٱلْجَزَآءَ ٱلْأَوْفَىٰ","en":"Then he will be recompensed for it with the fullest recompense -","tr":"Thumma yujzahu aljazaa al-awfa","juz":27,"page":527},{"s":53,"a":42,"key":"53:42","ar":"وَأَنَّ إِلَىٰ رَبِّكَ ٱلْمُنتَهَىٰ","en":"And that to your Lord is the finality","tr":"Waanna ila rabbika almuntaha","juz":27,"page":527},{"s":53,"a":43,"key":"53:43","ar":"وَأَنَّهُۥ هُوَ أَضْحَكَ وَأَبْكَىٰ","en":"And that it is He who makes [one] laugh and weep","tr":"Waannahu huwa adhaka waabka","juz":27,"page":527},{"s":53,"a":44,"key":"53:44","ar":"وَأَنَّهُۥ هُوَ أَمَاتَ وَأَحْيَا","en":"And that it is He who causes death and gives life","tr":"Waannahu huwa amata waahya","juz":27,"page":527},{"s":53,"a":45,"key":"53:45","ar":"وَأَنَّهُۥ خَلَقَ ٱلزَّوْجَيْنِ ٱلذَّكَرَ وَٱلْأُنثَىٰ","en":"And that He creates the two mates - the male and female -","tr":"Waannahu khalaqa azzawjayni aththakarawal-ontha","juz":27,"page":528},{"s":53,"a":46,"key":"53:46","ar":"مِن نُّطْفَةٍ إِذَا تُمْنَىٰ","en":"From a sperm-drop when it is emitted","tr":"Min nutfatin itha tumna","juz":27,"page":528},{"s":53,"a":47,"key":"53:47","ar":"وَأَنَّ عَلَيْهِ ٱلنَّشْأَةَ ٱلْأُخْرَىٰ","en":"And that [incumbent] upon Him is the other [i.e., next] creation.","tr":"Waanna AAalayhi annash-ata al-okhra","juz":27,"page":528},{"s":53,"a":48,"key":"53:48","ar":"وَأَنَّهُۥ هُوَ أَغْنَىٰ وَأَقْنَىٰ","en":"And that it is He who enriches and suffices","tr":"Waannahu huwa aghna waaqna","juz":27,"page":528},{"s":53,"a":49,"key":"53:49","ar":"وَأَنَّهُۥ هُوَ رَبُّ ٱلشِّعْرَىٰ","en":"And that it is He who is the Lord of Sirius1.","tr":"Waannahu huwa rabbu ashshiAAra","juz":27,"page":528},{"s":53,"a":50,"key":"53:50","ar":"وَأَنَّهُۥٓ أَهْلَكَ عَادًا ٱلْأُولَىٰ","en":"And that He destroyed the first [people of] ʿAad.","tr":"Waannahu ahlaka AAadan al-oola","juz":27,"page":528},{"s":53,"a":51,"key":"53:51","ar":"وَثَمُودَا۟ فَمَآ أَبْقَىٰ","en":"And Thamūd - and He did not spare [them] -","tr":"Wathamooda fama abqa","juz":27,"page":528},{"s":53,"a":52,"key":"53:52","ar":"وَقَوْمَ نُوحٍ مِّن قَبْلُ ۖ إِنَّهُمْ كَانُوا۟ هُمْ أَظْلَمَ وَأَطْغَىٰ","en":"And the people of Noah before. Indeed, it was they who were [even] more unjust and oppressing.","tr":"Waqawma noohin min qablu innahum kanoohum athlama waatgha","juz":27,"page":528},{"s":53,"a":53,"key":"53:53","ar":"وَٱلْمُؤْتَفِكَةَ أَهْوَىٰ","en":"And the overturned towns1 He hurled down.","tr":"Walmu/tafikata ahwa","juz":27,"page":528},{"s":53,"a":54,"key":"53:54","ar":"فَغَشَّىٰهَا مَا غَشَّىٰ","en":"And covered them by that which He covered.1","tr":"Faghashshaha ma ghashsha","juz":27,"page":528},{"s":53,"a":55,"key":"53:55","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكَ تَتَمَارَىٰ","en":"Then which of the favors of your Lord do you doubt?","tr":"Fabi-ayyi ala-i rabbika tatamara","juz":27,"page":528},{"s":53,"a":56,"key":"53:56","ar":"هَـٰذَا نَذِيرٌ مِّنَ ٱلنُّذُرِ ٱلْأُولَىٰٓ","en":"This [Prophet (ﷺ)] is a warner from [i.e., like] the former warners.","tr":"Hatha natheerun mina annuthurial-oola","juz":27,"page":528},{"s":53,"a":57,"key":"53:57","ar":"أَزِفَتِ ٱلْـَٔازِفَةُ","en":"The Approaching Day has approached.","tr":"Azifati al-azifat","juz":27,"page":528},{"s":53,"a":58,"key":"53:58","ar":"لَيْسَ لَهَا مِن دُونِ ٱللَّهِ كَاشِفَةٌ","en":"Of it, [from those] besides Allāh, there is no remover.","tr":"Laysa laha min dooni Allahi kashifat","juz":27,"page":528},{"s":53,"a":59,"key":"53:59","ar":"أَفَمِنْ هَـٰذَا ٱلْحَدِيثِ تَعْجَبُونَ","en":"Then at this statement do you wonder?","tr":"Afamin hatha alhadeethitaAAjaboon","juz":27,"page":528},{"s":53,"a":60,"key":"53:60","ar":"وَتَضْحَكُونَ وَلَا تَبْكُونَ","en":"And you laugh and do not weep","tr":"Watadhakoona wala tabkoon","juz":27,"page":528},{"s":53,"a":61,"key":"53:61","ar":"وَأَنتُمْ سَـٰمِدُونَ","en":"While you are proudly sporting?1","tr":"Waantum samidoon","juz":27,"page":528},{"s":53,"a":62,"key":"53:62","ar":"فَٱسْجُدُوا۟ لِلَّهِ وَٱعْبُدُوا۟ ۩","en":"So prostrate to Allāh and worship [Him].","tr":"Fasjudoo lillahi waAAbudoo","juz":27,"page":528},{"s":54,"a":1,"key":"54:1","ar":" ٱقْتَرَبَتِ ٱلسَّاعَةُ وَٱنشَقَّ ٱلْقَمَرُ","en":"The Hour has come near, and the moon has split [in two].1","tr":"Iqtarabati assaAAatu wanshaqqaalqamar","juz":27,"page":528},{"s":54,"a":2,"key":"54:2","ar":"وَإِن يَرَوْا۟ ءَايَةً يُعْرِضُوا۟ وَيَقُولُوا۟ سِحْرٌ مُّسْتَمِرٌّ","en":"And if they see a sign [i.e., miracle], they turn away and say, \"Passing magic.\"1","tr":"Wa-in yaraw ayatan yuAAridoowayaqooloo sihrun mustamirr","juz":27,"page":528},{"s":54,"a":3,"key":"54:3","ar":"وَكَذَّبُوا۟ وَٱتَّبَعُوٓا۟ أَهْوَآءَهُمْ ۚ وَكُلُّ أَمْرٍ مُّسْتَقِرٌّ","en":"And they denied and followed their inclinations. But for every matter is a [time of] settlement.","tr":"Wakaththaboo wattabaAAoo ahwaahumwakullu amrin mustaqirr","juz":27,"page":528},{"s":54,"a":4,"key":"54:4","ar":"وَلَقَدْ جَآءَهُم مِّنَ ٱلْأَنۢبَآءِ مَا فِيهِ مُزْدَجَرٌ","en":"And there has already come to them of information that in which there is deterrence.","tr":"Walaqad jaahum mina al-anba-i mafeehi muzdajar","juz":27,"page":528},{"s":54,"a":5,"key":"54:5","ar":"حِكْمَةٌۢ بَـٰلِغَةٌ ۖ فَمَا تُغْنِ ٱلنُّذُرُ","en":"Extensive wisdom - but warning does not avail [them].","tr":"Hikmatun balighatun famatughnee annuthur","juz":27,"page":528},{"s":54,"a":6,"key":"54:6","ar":"فَتَوَلَّ عَنْهُمْ ۘ يَوْمَ يَدْعُ ٱلدَّاعِ إِلَىٰ شَىْءٍ نُّكُرٍ","en":"So leave them, [O Muḥammad]. The Day the Caller1 calls to something forbidding,","tr":"Fatawalla AAanhum yawma yadAAu addaAAiila shay-in nukur","juz":27,"page":528},{"s":54,"a":7,"key":"54:7","ar":"خُشَّعًا أَبْصَـٰرُهُمْ يَخْرُجُونَ مِنَ ٱلْأَجْدَاثِ كَأَنَّهُمْ جَرَادٌ مُّنتَشِرٌ","en":"Their eyes humbled, they will emerge from the graves as if they were locusts spreading,","tr":"KhushshaAAan absaruhum yakhrujoonamina al-ajdathi kaannahum jaradun muntashir","juz":27,"page":529},{"s":54,"a":8,"key":"54:8","ar":"مُّهْطِعِينَ إِلَى ٱلدَّاعِ ۖ يَقُولُ ٱلْكَـٰفِرُونَ هَـٰذَا يَوْمٌ عَسِرٌ","en":"Racing ahead toward the Caller. The disbelievers will say, \"This is a difficult Day.\"","tr":"MuhtiAAeena ila addaAAiyaqoolu alkafiroona hatha yawmun AAasir","juz":27,"page":529},{"s":54,"a":9,"key":"54:9","ar":"۞ كَذَّبَتْ قَبْلَهُمْ قَوْمُ نُوحٍ فَكَذَّبُوا۟ عَبْدَنَا وَقَالُوا۟ مَجْنُونٌ وَٱزْدُجِرَ","en":"The people of Noah denied before them, and they denied Our servant and said, \"A madman,\" and he was repelled.","tr":"Kaththabat qablahum qawmu noohinfakaththaboo AAabdana waqaloo majnoonun wazdujir","juz":27,"page":529},{"s":54,"a":10,"key":"54:10","ar":"فَدَعَا رَبَّهُۥٓ أَنِّى مَغْلُوبٌ فَٱنتَصِرْ","en":"So he invoked his Lord, \"Indeed, I am overpowered, so help.\"","tr":"FadaAAa rabbahu annee maghloobun fantasir","juz":27,"page":529},{"s":54,"a":11,"key":"54:11","ar":"فَفَتَحْنَآ أَبْوَٰبَ ٱلسَّمَآءِ بِمَآءٍ مُّنْهَمِرٍ","en":"Then We opened the gates of the heaven with rain pouring down","tr":"Fafatahna abwaba assama-ibima-in munhamir","juz":27,"page":529},{"s":54,"a":12,"key":"54:12","ar":"وَفَجَّرْنَا ٱلْأَرْضَ عُيُونًا فَٱلْتَقَى ٱلْمَآءُ عَلَىٰٓ أَمْرٍ قَدْ قُدِرَ","en":"And caused the earth to burst with springs, and the waters met for a matter already predestined.","tr":"Wafajjarna al-arda AAuyoonanfaltaqa almao AAala amrin qad qudir","juz":27,"page":529},{"s":54,"a":13,"key":"54:13","ar":"وَحَمَلْنَـٰهُ عَلَىٰ ذَاتِ أَلْوَٰحٍ وَدُسُرٍ","en":"And We carried him on a [construction of] planks and nails,","tr":"Wahamalnahu AAala thatialwahin wadusur","juz":27,"page":529},{"s":54,"a":14,"key":"54:14","ar":"تَجْرِى بِأَعْيُنِنَا جَزَآءً لِّمَن كَانَ كُفِرَ","en":"Sailing under Our observation as reward for he who had been denied.","tr":"Tajree bi-aAAyunina jazaanliman kana kufir","juz":27,"page":529},{"s":54,"a":15,"key":"54:15","ar":"وَلَقَد تَّرَكْنَـٰهَآ ءَايَةً فَهَلْ مِن مُّدَّكِرٍ","en":"And We left it as a sign, so is there any who will remember?","tr":"Walaqad taraknaha ayatanfahal min muddakir","juz":27,"page":529},{"s":54,"a":16,"key":"54:16","ar":"فَكَيْفَ كَانَ عَذَابِى وَنُذُرِ","en":"And how [severe] were My punishment and warning.1","tr":"Fakayfa kana AAathabee wanuthur","juz":27,"page":529},{"s":54,"a":17,"key":"54:17","ar":"وَلَقَدْ يَسَّرْنَا ٱلْقُرْءَانَ لِلذِّكْرِ فَهَلْ مِن مُّدَّكِرٍ","en":"And We have certainly made the Qur’ān easy for remembrance, so is there any who will remember?","tr":"Walaqad yassarna alqur-ana liththikrifahal min muddakir","juz":27,"page":529},{"s":54,"a":18,"key":"54:18","ar":"كَذَّبَتْ عَادٌ فَكَيْفَ كَانَ عَذَابِى وَنُذُرِ","en":"ʿAad denied; and how [severe] were My punishment and warning.","tr":"Kaththabat AAadun fakayfa kanaAAathabee wanuthur","juz":27,"page":529},{"s":54,"a":19,"key":"54:19","ar":"إِنَّآ أَرْسَلْنَا عَلَيْهِمْ رِيحًا صَرْصَرًا فِى يَوْمِ نَحْسٍ مُّسْتَمِرٍّ","en":"Indeed, We sent upon them a screaming wind on a day of continuous misfortune,","tr":"Inna arsalna AAalayhim reehansarsaran fee yawmi nahsin mustamirr","juz":27,"page":529},{"s":54,"a":20,"key":"54:20","ar":"تَنزِعُ ٱلنَّاسَ كَأَنَّهُمْ أَعْجَازُ نَخْلٍ مُّنقَعِرٍ","en":"Extracting the people1 as if they were trunks of palm trees uprooted.","tr":"TanziAAu annasa kaannahumaAAjazu nakhlin munqaAAir","juz":27,"page":529},{"s":54,"a":21,"key":"54:21","ar":"فَكَيْفَ كَانَ عَذَابِى وَنُذُرِ","en":"And how [severe] were My punishment and warning.","tr":"Fakayfa kana AAathabee wanuthur","juz":27,"page":529},{"s":54,"a":22,"key":"54:22","ar":"وَلَقَدْ يَسَّرْنَا ٱلْقُرْءَانَ لِلذِّكْرِ فَهَلْ مِن مُّدَّكِرٍ","en":"And We have certainly made the Qur’ān easy for remembrance, so is there any who will remember?","tr":"Walaqad yassarna alqur-ana liththikrifahal min muddakir","juz":27,"page":529},{"s":54,"a":23,"key":"54:23","ar":"كَذَّبَتْ ثَمُودُ بِٱلنُّذُرِ","en":"Thamūd denied the warning.","tr":"Kaththabat thamoodu binnuthur","juz":27,"page":529},{"s":54,"a":24,"key":"54:24","ar":"فَقَالُوٓا۟ أَبَشَرًا مِّنَّا وَٰحِدًا نَّتَّبِعُهُۥٓ إِنَّآ إِذًا لَّفِى ضَلَـٰلٍ وَسُعُرٍ","en":"And said, \"Is it one human being1 among us that we should follow? Indeed, we would then be in error and madness.","tr":"Faqaloo abasharan minna wahidannattabiAAuhu inna ithan lafee dalalinwasuAAur","juz":27,"page":529},{"s":54,"a":25,"key":"54:25","ar":"أَءُلْقِىَ ٱلذِّكْرُ عَلَيْهِ مِنۢ بَيْنِنَا بَلْ هُوَ كَذَّابٌ أَشِرٌ","en":"Has the message been sent down upon him from among us? Rather, he is an insolent liar.\"","tr":"Aolqiya aththikru AAalayhimin baynina bal huwa kaththabun ashir","juz":27,"page":529},{"s":54,"a":26,"key":"54:26","ar":"سَيَعْلَمُونَ غَدًا مَّنِ ٱلْكَذَّابُ ٱلْأَشِرُ","en":"They will know tomorrow who is the insolent liar.","tr":"SayaAAlamoona ghadan mani alkaththabual-ashir","juz":27,"page":529},{"s":54,"a":27,"key":"54:27","ar":"إِنَّا مُرْسِلُوا۟ ٱلنَّاقَةِ فِتْنَةً لَّهُمْ فَٱرْتَقِبْهُمْ وَٱصْطَبِرْ","en":"Indeed, We are sending the she-camel as trial for them, so watch them and be patient.1","tr":"Inna mursiloo annaqatifitnatan lahum fartaqibhum wastabir","juz":27,"page":529},{"s":54,"a":28,"key":"54:28","ar":"وَنَبِّئْهُمْ أَنَّ ٱلْمَآءَ قِسْمَةٌۢ بَيْنَهُمْ ۖ كُلُّ شِرْبٍ مُّحْتَضَرٌ","en":"And inform them that the water is shared between them,1 each [day of] drink attended [by turn].","tr":"Wanabbi/hum anna almaa qismatunbaynahum kullu shirbin muhtadar","juz":27,"page":530},{"s":54,"a":29,"key":"54:29","ar":"فَنَادَوْا۟ صَاحِبَهُمْ فَتَعَاطَىٰ فَعَقَرَ","en":"But they called their companion,1 and he dared2 and hamstrung [her].","tr":"Fanadaw sahibahum fataAAatafaAAaqar","juz":27,"page":530},{"s":54,"a":30,"key":"54:30","ar":"فَكَيْفَ كَانَ عَذَابِى وَنُذُرِ","en":"And how [severe] were My punishment and warning.","tr":"Fakayfa kana AAathabee wanuthur","juz":27,"page":530},{"s":54,"a":31,"key":"54:31","ar":"إِنَّآ أَرْسَلْنَا عَلَيْهِمْ صَيْحَةً وَٰحِدَةً فَكَانُوا۟ كَهَشِيمِ ٱلْمُحْتَظِرِ","en":"Indeed, We sent upon them one shriek [i.e., blast from the sky], and they became like the dry twig fragments of an [animal] pen.","tr":"Inna arsalna AAalayhim sayhatanwahidatan fakanoo kahasheemi almuhtathir","juz":27,"page":530},{"s":54,"a":32,"key":"54:32","ar":"وَلَقَدْ يَسَّرْنَا ٱلْقُرْءَانَ لِلذِّكْرِ فَهَلْ مِن مُّدَّكِرٍ","en":"And We have certainly made the Qur’ān easy for remembrance, so is there any who will remember?","tr":"Walaqad yassarna alqur-ana liththikrifahal min muddakir","juz":27,"page":530},{"s":54,"a":33,"key":"54:33","ar":"كَذَّبَتْ قَوْمُ لُوطٍۭ بِٱلنُّذُرِ","en":"The people of Lot denied the warning.","tr":"Kaththabat qawmu lootin binnuthur","juz":27,"page":530},{"s":54,"a":34,"key":"54:34","ar":"إِنَّآ أَرْسَلْنَا عَلَيْهِمْ حَاصِبًا إِلَّآ ءَالَ لُوطٍ ۖ نَّجَّيْنَـٰهُم بِسَحَرٍ","en":"Indeed, We sent upon them a storm of stones, except the family of Lot - We saved them before dawn.","tr":"Inna arsalna AAalayhim hasibanilla ala lootin najjaynahum bisahar","juz":27,"page":530},{"s":54,"a":35,"key":"54:35","ar":"نِّعْمَةً مِّنْ عِندِنَا ۚ كَذَٰلِكَ نَجْزِى مَن شَكَرَ","en":"As favor from Us. Thus do We reward he who is grateful.","tr":"NiAAmatan min AAindina kathalikanajzee man shakar","juz":27,"page":530},{"s":54,"a":36,"key":"54:36","ar":"وَلَقَدْ أَنذَرَهُم بَطْشَتَنَا فَتَمَارَوْا۟ بِٱلنُّذُرِ","en":"And he had already warned them of Our assault, but they disputed the warning.","tr":"Walaqad antharahum batshatanafatamaraw binnuthur","juz":27,"page":530},{"s":54,"a":37,"key":"54:37","ar":"وَلَقَدْ رَٰوَدُوهُ عَن ضَيْفِهِۦ فَطَمَسْنَآ أَعْيُنَهُمْ فَذُوقُوا۟ عَذَابِى وَنُذُرِ","en":"And they had demanded from him his guests, but We obliterated their eyes, [saying], \"Taste My punishment and warning.\"","tr":"Walaqad rawadoohu AAan dayfihifatamasna aAAyunahum fathooqoo AAathabeewanuthur","juz":27,"page":530},{"s":54,"a":38,"key":"54:38","ar":"وَلَقَدْ صَبَّحَهُم بُكْرَةً عَذَابٌ مُّسْتَقِرٌّ","en":"And there came upon them by morning an abiding punishment.","tr":"Walaqad sabbahahum bukratanAAathabun mustaqirr","juz":27,"page":530},{"s":54,"a":39,"key":"54:39","ar":"فَذُوقُوا۟ عَذَابِى وَنُذُرِ","en":"So taste My punishment and warning.","tr":"Fathooqoo AAathabee wanuthur","juz":27,"page":530},{"s":54,"a":40,"key":"54:40","ar":"وَلَقَدْ يَسَّرْنَا ٱلْقُرْءَانَ لِلذِّكْرِ فَهَلْ مِن مُّدَّكِرٍ","en":"And We have certainly made the Qur’ān easy for remembrance, so is there any who will remember?","tr":"Walaqad yassarna alqur-ana liththikrifahal min muddakir","juz":27,"page":530},{"s":54,"a":41,"key":"54:41","ar":"وَلَقَدْ جَآءَ ءَالَ فِرْعَوْنَ ٱلنُّذُرُ","en":"And there certainly came to the people of Pharaoh warning.","tr":"Walaqad jaa ala firAAawna annuthur","juz":27,"page":530},{"s":54,"a":42,"key":"54:42","ar":"كَذَّبُوا۟ بِـَٔايَـٰتِنَا كُلِّهَا فَأَخَذْنَـٰهُمْ أَخْذَ عَزِيزٍ مُّقْتَدِرٍ","en":"They denied Our signs, all of them, so We seized them with a seizure of one Exalted in Might and Perfect in Ability.","tr":"Kaththaboo bi-ayatinakulliha faakhathnahum akhthaAAazeezin muqtadir","juz":27,"page":530},{"s":54,"a":43,"key":"54:43","ar":"أَكُفَّارُكُمْ خَيْرٌ مِّنْ أُو۟لَـٰٓئِكُمْ أَمْ لَكُم بَرَآءَةٌ فِى ٱلزُّبُرِ","en":"Are your disbelievers better than those [former ones], or have you immunity in the scriptures?","tr":"Akuffarukum khayrun min ola-ikumam lakum baraatun fee azzubur","juz":27,"page":530},{"s":54,"a":44,"key":"54:44","ar":"أَمْ يَقُولُونَ نَحْنُ جَمِيعٌ مُّنتَصِرٌ","en":"Or do they say, \"We are an assembly supporting [each other]\"?","tr":"Am yaqooloona nahnu jameeAAun muntasir","juz":27,"page":530},{"s":54,"a":45,"key":"54:45","ar":"سَيُهْزَمُ ٱلْجَمْعُ وَيُوَلُّونَ ٱلدُّبُرَ","en":"[Their] assembly will be defeated, and they will turn their backs [in retreat].1","tr":"Sayuhzamu aljamAAu wayuwalloona addubur","juz":27,"page":530},{"s":54,"a":46,"key":"54:46","ar":"بَلِ ٱلسَّاعَةُ مَوْعِدُهُمْ وَٱلسَّاعَةُ أَدْهَىٰ وَأَمَرُّ","en":"But the Hour is their appointment [for due punishment], and the Hour is more disastrous and more bitter.","tr":"Bali assaAAatu mawAAiduhum wassaAAatuadha waamar","juz":27,"page":530},{"s":54,"a":47,"key":"54:47","ar":"إِنَّ ٱلْمُجْرِمِينَ فِى ضَلَـٰلٍ وَسُعُرٍ","en":"Indeed, the criminals are in error and madness.1.","tr":"Inna almujrimeena fee dalalinwasuAAur","juz":27,"page":530},{"s":54,"a":48,"key":"54:48","ar":"يَوْمَ يُسْحَبُونَ فِى ٱلنَّارِ عَلَىٰ وُجُوهِهِمْ ذُوقُوا۟ مَسَّ سَقَرَ","en":"The Day they are dragged into the Fire on their faces [it will be said], \"Taste the touch of Saqar.\"1","tr":"Yawma yushaboona fee annariAAala wujoohihim thooqoo massa saqar","juz":27,"page":530},{"s":54,"a":49,"key":"54:49","ar":"إِنَّا كُلَّ شَىْءٍ خَلَقْنَـٰهُ بِقَدَرٍ","en":"Indeed, all things We created with predestination.","tr":"Inna kulla shay-in khalaqnahubiqadar","juz":27,"page":530},{"s":54,"a":50,"key":"54:50","ar":"وَمَآ أَمْرُنَآ إِلَّا وَٰحِدَةٌ كَلَمْحٍۭ بِٱلْبَصَرِ","en":"And Our command is but one, like a glance of the eye.","tr":"Wama amruna illa wahidatunkalamhin bilbasar","juz":27,"page":531},{"s":54,"a":51,"key":"54:51","ar":"وَلَقَدْ أَهْلَكْنَآ أَشْيَاعَكُمْ فَهَلْ مِن مُّدَّكِرٍ","en":"And We have already destroyed your kinds,1 so is there any who will remember?","tr":"Walaqad ahlakna ashyaAAakumfahal min muddakir","juz":27,"page":531},{"s":54,"a":52,"key":"54:52","ar":"وَكُلُّ شَىْءٍ فَعَلُوهُ فِى ٱلزُّبُرِ","en":"And everything they did is in written records.","tr":"Wakullu shay-in faAAaloohu fee azzubur","juz":27,"page":531},{"s":54,"a":53,"key":"54:53","ar":"وَكُلُّ صَغِيرٍ وَكَبِيرٍ مُّسْتَطَرٌ","en":"And every small and great [thing] is inscribed.","tr":"Wakullu sagheerin wakabeerin mustatar","juz":27,"page":531},{"s":54,"a":54,"key":"54:54","ar":"إِنَّ ٱلْمُتَّقِينَ فِى جَنَّـٰتٍ وَنَهَرٍ","en":"Indeed, the righteous will be among gardens and rivers,","tr":"Inna almuttaqeena fee jannatinwanahar","juz":27,"page":531},{"s":54,"a":55,"key":"54:55","ar":"فِى مَقْعَدِ صِدْقٍ عِندَ مَلِيكٍ مُّقْتَدِرٍۭ","en":"In a seat of honor near a Sovereign, Perfect in Ability.1","tr":"Fee maqAAadi sidqin AAinda maleekinmuqtadir","juz":27,"page":531},{"s":55,"a":1,"key":"55:1","ar":" ٱلرَّحْمَـٰنُ","en":"The Most Merciful","tr":"Arrahman","juz":27,"page":531},{"s":55,"a":2,"key":"55:2","ar":"عَلَّمَ ٱلْقُرْءَانَ","en":"Taught the Qur’ān,","tr":"AAallama alqur-an","juz":27,"page":531},{"s":55,"a":3,"key":"55:3","ar":"خَلَقَ ٱلْإِنسَـٰنَ","en":"Created man,","tr":"Khalaqa al-insan","juz":27,"page":531},{"s":55,"a":4,"key":"55:4","ar":"عَلَّمَهُ ٱلْبَيَانَ","en":"[And] taught him eloquence.","tr":"AAallamahu albayan","juz":27,"page":531},{"s":55,"a":5,"key":"55:5","ar":"ٱلشَّمْسُ وَٱلْقَمَرُ بِحُسْبَانٍ","en":"The sun and the moon [move] by precise calculation,","tr":"Ashshamsu walqamaru bihusban","juz":27,"page":531},{"s":55,"a":6,"key":"55:6","ar":"وَٱلنَّجْمُ وَٱلشَّجَرُ يَسْجُدَانِ","en":"And the stars and trees prostrate.1","tr":"Wannajmu washshajaru yasjudan","juz":27,"page":531},{"s":55,"a":7,"key":"55:7","ar":"وَٱلسَّمَآءَ رَفَعَهَا وَوَضَعَ ٱلْمِيزَانَ","en":"And the heaven He raised and imposed the balance","tr":"Wassamaa rafaAAahawawadaAAa almeezan","juz":27,"page":531},{"s":55,"a":8,"key":"55:8","ar":"أَلَّا تَطْغَوْا۟ فِى ٱلْمِيزَانِ","en":"That you not transgress within the balance.","tr":"Alla tatghaw fee almeezan","juz":27,"page":531},{"s":55,"a":9,"key":"55:9","ar":"وَأَقِيمُوا۟ ٱلْوَزْنَ بِٱلْقِسْطِ وَلَا تُخْسِرُوا۟ ٱلْمِيزَانَ","en":"And establish weight in justice and do not make deficient the balance.","tr":"Waaqeemoo alwazna bilqisti walatukhsiroo almeezan","juz":27,"page":531},{"s":55,"a":10,"key":"55:10","ar":"وَٱلْأَرْضَ وَضَعَهَا لِلْأَنَامِ","en":"And the earth He laid [out] for the creatures.","tr":"Wal-arda wadaAAahalil-anam","juz":27,"page":531},{"s":55,"a":11,"key":"55:11","ar":"فِيهَا فَـٰكِهَةٌ وَٱلنَّخْلُ ذَاتُ ٱلْأَكْمَامِ","en":"Therein is fruit and palm trees having sheaths [of dates]","tr":"Feeha fakihatun wannakhluthatu al-akmam","juz":27,"page":531},{"s":55,"a":12,"key":"55:12","ar":"وَٱلْحَبُّ ذُو ٱلْعَصْفِ وَٱلرَّيْحَانُ","en":"And grain having husks and scented plants.","tr":"Walhabbu thoo alAAasfiwarrayhan","juz":27,"page":531},{"s":55,"a":13,"key":"55:13","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?1","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":531},{"s":55,"a":14,"key":"55:14","ar":"خَلَقَ ٱلْإِنسَـٰنَ مِن صَلْصَـٰلٍ كَٱلْفَخَّارِ","en":"He created man from clay like [that of] pottery.","tr":"Khalaqa al-insana min salsalinkalfakhkhar","juz":27,"page":531},{"s":55,"a":15,"key":"55:15","ar":"وَخَلَقَ ٱلْجَآنَّ مِن مَّارِجٍ مِّن نَّارٍ","en":"And He created the jinn from a smokeless flame of fire.","tr":"Wakhalaqa aljanna min marijinmin nar","juz":27,"page":531},{"s":55,"a":16,"key":"55:16","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":531},{"s":55,"a":17,"key":"55:17","ar":"رَبُّ ٱلْمَشْرِقَيْنِ وَرَبُّ ٱلْمَغْرِبَيْنِ","en":"[He is] Lord of the two sunrises and Lord of the two sunsets.1","tr":"Rabbu almashriqayni warabbu almaghribayn","juz":27,"page":532},{"s":55,"a":18,"key":"55:18","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":19,"key":"55:19","ar":"مَرَجَ ٱلْبَحْرَيْنِ يَلْتَقِيَانِ","en":"He released the two seas,1 meeting [one another];","tr":"Maraja albahrayni yaltaqiyan","juz":27,"page":532},{"s":55,"a":20,"key":"55:20","ar":"بَيْنَهُمَا بَرْزَخٌ لَّا يَبْغِيَانِ","en":"Between them is a barrier so neither of them transgresses.","tr":"Baynahuma barzakhun la yabghiyan","juz":27,"page":532},{"s":55,"a":21,"key":"55:21","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":22,"key":"55:22","ar":"يَخْرُجُ مِنْهُمَا ٱللُّؤْلُؤُ وَٱلْمَرْجَانُ","en":"From both of them emerge pearl and coral.","tr":"Yakhruju minhuma allu/luo walmarjan","juz":27,"page":532},{"s":55,"a":23,"key":"55:23","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththibani","juz":27,"page":532},{"s":55,"a":24,"key":"55:24","ar":"وَلَهُ ٱلْجَوَارِ ٱلْمُنشَـَٔاتُ فِى ٱلْبَحْرِ كَٱلْأَعْلَـٰمِ","en":"And to Him belong the ships [with sails] elevated in the sea like mountains.","tr":"Walahu aljawari almunshaatufee albahri kal-aAAlam","juz":27,"page":532},{"s":55,"a":25,"key":"55:25","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":26,"key":"55:26","ar":"كُلُّ مَنْ عَلَيْهَا فَانٍ","en":"Everyone upon it [i.e., the earth] will perish,","tr":"Kullu man AAalayha fan","juz":27,"page":532},{"s":55,"a":27,"key":"55:27","ar":"وَيَبْقَىٰ وَجْهُ رَبِّكَ ذُو ٱلْجَلَـٰلِ وَٱلْإِكْرَامِ","en":"And there will remain the Face1 of your Lord, Owner of Majesty and Honor.","tr":"Wayabqa wajhu rabbika thooaljalali wal-ikram","juz":27,"page":532},{"s":55,"a":28,"key":"55:28","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":29,"key":"55:29","ar":"يَسْـَٔلُهُۥ مَن فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ كُلَّ يَوْمٍ هُوَ فِى شَأْنٍ","en":"Whoever is within the heavens and earth asks Him; every day He is in [i.e., bringing about] a matter.1","tr":"Yas-aluhu man fee assamawatiwal-ardi kulla yawmin huwa fee sha/n","juz":27,"page":532},{"s":55,"a":30,"key":"55:30","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":31,"key":"55:31","ar":"سَنَفْرُغُ لَكُمْ أَيُّهَ ٱلثَّقَلَانِ","en":"We will attend to you, O prominent beings.1","tr":"Sanafrughu lakum ayyuha aththaqalan","juz":27,"page":532},{"s":55,"a":32,"key":"55:32","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":33,"key":"55:33","ar":"يَـٰمَعْشَرَ ٱلْجِنِّ وَٱلْإِنسِ إِنِ ٱسْتَطَعْتُمْ أَن تَنفُذُوا۟ مِنْ أَقْطَارِ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ فَٱنفُذُوا۟ ۚ لَا تَنفُذُونَ إِلَّا بِسُلْطَـٰنٍ","en":"O company of jinn and mankind, if you are able to pass beyond the regions of the heavens and the earth, then pass. You will not pass except by authority [from Allāh].","tr":"Ya maAAshara aljinni wal-insiini istataAAtum an tanfuthoo min aqtari assamawatiwal-ardi fanfuthoo la tanfuthoonailla bisultan","juz":27,"page":532},{"s":55,"a":34,"key":"55:34","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":35,"key":"55:35","ar":"يُرْسَلُ عَلَيْكُمَا شُوَاظٌ مِّن نَّارٍ وَنُحَاسٌ فَلَا تَنتَصِرَانِ","en":"There will be sent upon you a flame of fire and smoke,1 and you will not defend yourselves.","tr":"Yursalu AAalaykuma shuwathunmin narin wanuhasun fala tantasiran","juz":27,"page":532},{"s":55,"a":36,"key":"55:36","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":37,"key":"55:37","ar":"فَإِذَا ٱنشَقَّتِ ٱلسَّمَآءُ فَكَانَتْ وَرْدَةً كَٱلدِّهَانِ","en":"And when the heaven is split open and becomes rose-colored like oil1 -","tr":"Fa-itha inshaqqati assamaofakanat wardatan kaddihan","juz":27,"page":532},{"s":55,"a":38,"key":"55:38","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny? -","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":39,"key":"55:39","ar":"فَيَوْمَئِذٍ لَّا يُسْـَٔلُ عَن ذَنۢبِهِۦٓ إِنسٌ وَلَا جَآنٌّ","en":"Then on that Day none will be asked about his sin among men or jinn.1","tr":"Fayawma-ithin la yus-alu AAan thanbihiinsun wala jan","juz":27,"page":532},{"s":55,"a":40,"key":"55:40","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":532},{"s":55,"a":41,"key":"55:41","ar":"يُعْرَفُ ٱلْمُجْرِمُونَ بِسِيمَـٰهُمْ فَيُؤْخَذُ بِٱلنَّوَٰصِى وَٱلْأَقْدَامِ","en":"The criminals will be known by their marks, and they will be seized by the forelocks and the feet.","tr":"YuAArafu almujrimoona biseemahumfayu/khathu binnawasee wal-aqdam","juz":27,"page":533},{"s":55,"a":42,"key":"55:42","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":43,"key":"55:43","ar":"هَـٰذِهِۦ جَهَنَّمُ ٱلَّتِى يُكَذِّبُ بِهَا ٱلْمُجْرِمُونَ","en":"This is Hell, which the criminals deny.","tr":"Hathihi jahannamu allatee yukaththibubiha almujrimoon","juz":27,"page":533},{"s":55,"a":44,"key":"55:44","ar":"يَطُوفُونَ بَيْنَهَا وَبَيْنَ حَمِيمٍ ءَانٍ","en":"They will circulate between it and scalding water, heated [to the utmost degree].","tr":"Yatoofoona baynaha wabayna hameeminan","juz":27,"page":533},{"s":55,"a":45,"key":"55:45","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":46,"key":"55:46","ar":"وَلِمَنْ خَافَ مَقَامَ رَبِّهِۦ جَنَّتَانِ","en":"But for he who has feared the position of his Lord1 are two gardens -","tr":"Waliman khafa maqama rabbihijannatan","juz":27,"page":533},{"s":55,"a":47,"key":"55:47","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny? -","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":48,"key":"55:48","ar":"ذَوَاتَآ أَفْنَانٍ","en":"Having [spreading] branches.","tr":"Thawata afnan","juz":27,"page":533},{"s":55,"a":49,"key":"55:49","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":50,"key":"55:50","ar":"فِيهِمَا عَيْنَانِ تَجْرِيَانِ","en":"In both of them are two springs, flowing.","tr":"Feehima AAaynani tajriyan","juz":27,"page":533},{"s":55,"a":51,"key":"55:51","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":52,"key":"55:52","ar":"فِيهِمَا مِن كُلِّ فَـٰكِهَةٍ زَوْجَانِ","en":"In both of them are of every fruit, two kinds.","tr":"Feehima min kulli fakihatinzawjan","juz":27,"page":533},{"s":55,"a":53,"key":"55:53","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":54,"key":"55:54","ar":"مُتَّكِـِٔينَ عَلَىٰ فُرُشٍۭ بَطَآئِنُهَا مِنْ إِسْتَبْرَقٍ ۚ وَجَنَى ٱلْجَنَّتَيْنِ دَانٍ","en":"[They are] reclining on beds whose linings are of silk brocade, and the fruit of the two gardens is hanging low.","tr":"Muttaki-eena AAala furushin bata-inuhamin istabraqin wajana aljannatayni dan","juz":27,"page":533},{"s":55,"a":55,"key":"55:55","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":56,"key":"55:56","ar":"فِيهِنَّ قَـٰصِرَٰتُ ٱلطَّرْفِ لَمْ يَطْمِثْهُنَّ إِنسٌ قَبْلَهُمْ وَلَا جَآنٌّ","en":"In them are women limiting [their] glances,1 untouched2 before them by man or jinnī -","tr":"Feehinna qasiratu attarfilam yatmithhunna insun qablahum wala jan","juz":27,"page":533},{"s":55,"a":57,"key":"55:57","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny? -","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":58,"key":"55:58","ar":"كَأَنَّهُنَّ ٱلْيَاقُوتُ وَٱلْمَرْجَانُ","en":"As if they were rubies and coral.1","tr":"Kaannahunna alyaqootu walmarjan","juz":27,"page":533},{"s":55,"a":59,"key":"55:59","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":60,"key":"55:60","ar":"هَلْ جَزَآءُ ٱلْإِحْسَـٰنِ إِلَّا ٱلْإِحْسَـٰنُ","en":"Is the reward for good [anything] but good?","tr":"Hal jazao al-ihsani illaal-ihsan","juz":27,"page":533},{"s":55,"a":61,"key":"55:61","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":62,"key":"55:62","ar":"وَمِن دُونِهِمَا جَنَّتَانِ","en":"And below them both [in excellence] are two [other] gardens -","tr":"Wamin doonihima jannatan","juz":27,"page":533},{"s":55,"a":63,"key":"55:63","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny? -","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":64,"key":"55:64","ar":"مُدْهَآمَّتَانِ","en":"Dark green [in color].","tr":"Mudhammatan","juz":27,"page":533},{"s":55,"a":65,"key":"55:65","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":66,"key":"55:66","ar":"فِيهِمَا عَيْنَانِ نَضَّاخَتَانِ","en":"In both of them are two springs, spouting.","tr":"Feehima AAaynani naddakhatan","juz":27,"page":533},{"s":55,"a":67,"key":"55:67","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":533},{"s":55,"a":68,"key":"55:68","ar":"فِيهِمَا فَـٰكِهَةٌ وَنَخْلٌ وَرُمَّانٌ","en":"In both of them are fruit and palm trees and pomegranates.","tr":"Feehima fakihatun wanakhlunwarumman","juz":27,"page":534},{"s":55,"a":69,"key":"55:69","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":534},{"s":55,"a":70,"key":"55:70","ar":"فِيهِنَّ خَيْرَٰتٌ حِسَانٌ","en":"In them are good and beautiful women -","tr":"Feehinna khayratun hisan","juz":27,"page":534},{"s":55,"a":71,"key":"55:71","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny? -","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":534},{"s":55,"a":72,"key":"55:72","ar":"حُورٌ مَّقْصُورَٰتٌ فِى ٱلْخِيَامِ","en":"Fair ones reserved in pavilions -","tr":"Hoorun maqsooratun feealkhiyam","juz":27,"page":534},{"s":55,"a":73,"key":"55:73","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny? -","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":534},{"s":55,"a":74,"key":"55:74","ar":"لَمْ يَطْمِثْهُنَّ إِنسٌ قَبْلَهُمْ وَلَا جَآنٌّ","en":"Untouched before them by man or jinnī -","tr":"Lam yatmithhunna insun qablahum walajan","juz":27,"page":534},{"s":55,"a":75,"key":"55:75","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny? -","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":534},{"s":55,"a":76,"key":"55:76","ar":"مُتَّكِـِٔينَ عَلَىٰ رَفْرَفٍ خُضْرٍ وَعَبْقَرِىٍّ حِسَانٍ","en":"Reclining on green cushions and beautiful fine carpets.","tr":"Muttaki-eena AAala rafrafin khudrinwaAAabqariyyin hisan","juz":27,"page":534},{"s":55,"a":77,"key":"55:77","ar":"فَبِأَىِّ ءَالَآءِ رَبِّكُمَا تُكَذِّبَانِ","en":"So which of the favors of your Lord would you deny?","tr":"Fabi-ayyi ala-i rabbikumatukaththiban","juz":27,"page":534},{"s":55,"a":78,"key":"55:78","ar":"تَبَـٰرَكَ ٱسْمُ رَبِّكَ ذِى ٱلْجَلَـٰلِ وَٱلْإِكْرَامِ","en":"Blessed is the name of your Lord, Owner of Majesty and Honor.","tr":"Tabaraka ismu rabbika theealjalali wal-ikram","juz":27,"page":534},{"s":56,"a":1,"key":"56:1","ar":" إِذَا وَقَعَتِ ٱلْوَاقِعَةُ","en":"When the Occurrence occurs,","tr":"Itha waqaAAati alwaqiAAat","juz":27,"page":534},{"s":56,"a":2,"key":"56:2","ar":"لَيْسَ لِوَقْعَتِهَا كَاذِبَةٌ","en":"There is, at its occurrence, no denial.","tr":"Laysa liwaqAAatiha kathiba","juz":27,"page":534},{"s":56,"a":3,"key":"56:3","ar":"خَافِضَةٌ رَّافِعَةٌ","en":"It will bring down [some] and raise up [others].1","tr":"Khafidatun rafiAAa","juz":27,"page":534},{"s":56,"a":4,"key":"56:4","ar":"إِذَا رُجَّتِ ٱلْأَرْضُ رَجًّا","en":"When the earth is shaken with convulsion","tr":"Itha rujjati al-ardu rajja","juz":27,"page":534},{"s":56,"a":5,"key":"56:5","ar":"وَبُسَّتِ ٱلْجِبَالُ بَسًّا","en":"And the mountains are broken down, crumbling","tr":"Wabussati aljibalu bassa","juz":27,"page":534},{"s":56,"a":6,"key":"56:6","ar":"فَكَانَتْ هَبَآءً مُّنۢبَثًّا","en":"And become dust dispersing,","tr":"Fakanat habaan munbaththa","juz":27,"page":534},{"s":56,"a":7,"key":"56:7","ar":"وَكُنتُمْ أَزْوَٰجًا ثَلَـٰثَةً","en":"And you become [of] three kinds:","tr":"Wakuntum azwajan thalatha","juz":27,"page":534},{"s":56,"a":8,"key":"56:8","ar":"فَأَصْحَـٰبُ ٱلْمَيْمَنَةِ مَآ أَصْحَـٰبُ ٱلْمَيْمَنَةِ","en":"Then the companions of the right - what are the companions of the right?1","tr":"Faas-habu almaymanati maas-habu almaymanat","juz":27,"page":534},{"s":56,"a":9,"key":"56:9","ar":"وَأَصْحَـٰبُ ٱلْمَشْـَٔمَةِ مَآ أَصْحَـٰبُ ٱلْمَشْـَٔمَةِ","en":"And the companions of the left - what are companions of the left?1","tr":"Waas-habu almash-amati maas-habu almash-amat","juz":27,"page":534},{"s":56,"a":10,"key":"56:10","ar":"وَٱلسَّـٰبِقُونَ ٱلسَّـٰبِقُونَ","en":"And the forerunners, the forerunners1 -","tr":"Wassabiqoona assabiqoon","juz":27,"page":534},{"s":56,"a":11,"key":"56:11","ar":"أُو۟لَـٰٓئِكَ ٱلْمُقَرَّبُونَ","en":"Those are the ones brought near [to Allāh]","tr":"Ola-ika almuqarraboon","juz":27,"page":534},{"s":56,"a":12,"key":"56:12","ar":"فِى جَنَّـٰتِ ٱلنَّعِيمِ","en":"In the Gardens of Pleasure,","tr":"Fee jannati annaAAeem","juz":27,"page":534},{"s":56,"a":13,"key":"56:13","ar":"ثُلَّةٌ مِّنَ ٱلْأَوَّلِينَ","en":"A [large] company of the former peoples","tr":"Thullatun mina al-awwaleen","juz":27,"page":534},{"s":56,"a":14,"key":"56:14","ar":"وَقَلِيلٌ مِّنَ ٱلْـَٔاخِرِينَ","en":"And a few of the later peoples,","tr":"Waqaleelun mina al-akhireena","juz":27,"page":534},{"s":56,"a":15,"key":"56:15","ar":"عَلَىٰ سُرُرٍ مَّوْضُونَةٍ","en":"On thrones woven [with ornament],","tr":"AAala sururin mawdoona","juz":27,"page":534},{"s":56,"a":16,"key":"56:16","ar":"مُّتَّكِـِٔينَ عَلَيْهَا مُتَقَـٰبِلِينَ","en":"Reclining on them, facing each other.","tr":"Muttaki-eena AAalayha mutaqabileen","juz":27,"page":534},{"s":56,"a":17,"key":"56:17","ar":"يَطُوفُ عَلَيْهِمْ وِلْدَٰنٌ مُّخَلَّدُونَ","en":"There will circulate among them young boys made eternal.","tr":"Yatoofu AAalayhim wildanunmukhalladoon","juz":27,"page":535},{"s":56,"a":18,"key":"56:18","ar":"بِأَكْوَابٍ وَأَبَارِيقَ وَكَأْسٍ مِّن مَّعِينٍ","en":"With vessels, pitchers and a cup [of wine] from a flowing spring -","tr":"Bi-akwabin waabareeqa waka/sinmin maAAeen","juz":27,"page":535},{"s":56,"a":19,"key":"56:19","ar":"لَّا يُصَدَّعُونَ عَنْهَا وَلَا يُنزِفُونَ","en":"No headache will they have therefrom, nor will they be intoxicated -","tr":"La yusaddaAAoona AAanhawala yunzifoon","juz":27,"page":535},{"s":56,"a":20,"key":"56:20","ar":"وَفَـٰكِهَةٍ مِّمَّا يَتَخَيَّرُونَ","en":"And fruit of what they select","tr":"Wafakihatin mimmayatakhayyaroon","juz":27,"page":535},{"s":56,"a":21,"key":"56:21","ar":"وَلَحْمِ طَيْرٍ مِّمَّا يَشْتَهُونَ","en":"And the meat of fowl, from whatever they desire.","tr":"Walahmi tayrin mimmayashtahoon","juz":27,"page":535},{"s":56,"a":22,"key":"56:22","ar":"وَحُورٌ عِينٌ","en":"And [for them are] fair women with large, [beautiful] eyes,","tr":"Wahoorun AAeen","juz":27,"page":535},{"s":56,"a":23,"key":"56:23","ar":"كَأَمْثَـٰلِ ٱللُّؤْلُؤِ ٱلْمَكْنُونِ","en":"The likenesses of pearls well-protected,","tr":"Kaamthali allu/lui almaknoon","juz":27,"page":535},{"s":56,"a":24,"key":"56:24","ar":"جَزَآءًۢ بِمَا كَانُوا۟ يَعْمَلُونَ","en":"As reward for what they used to do.","tr":"Jazaan bima kanooyaAAmaloon","juz":27,"page":535},{"s":56,"a":25,"key":"56:25","ar":"لَا يَسْمَعُونَ فِيهَا لَغْوًا وَلَا تَأْثِيمًا","en":"They will not hear therein ill speech or commission of sin -","tr":"La yasmaAAoona feeha laghwanwala ta/theema","juz":27,"page":535},{"s":56,"a":26,"key":"56:26","ar":"إِلَّا قِيلًا سَلَـٰمًا سَلَـٰمًا","en":"Only a saying [of] peace, peace.","tr":"Illa qeelan salaman salama","juz":27,"page":535},{"s":56,"a":27,"key":"56:27","ar":"وَأَصْحَـٰبُ ٱلْيَمِينِ مَآ أَصْحَـٰبُ ٱلْيَمِينِ","en":"The companions of the right - what are the companions of the right?","tr":"Waas-habu alyameeni maas-habu alyameen","juz":27,"page":535},{"s":56,"a":28,"key":"56:28","ar":"فِى سِدْرٍ مَّخْضُودٍ","en":"[They will be] among lote trees with thorns removed.","tr":"Fee sidrin makhdood","juz":27,"page":535},{"s":56,"a":29,"key":"56:29","ar":"وَطَلْحٍ مَّنضُودٍ","en":"And [banana] trees layered [with fruit].","tr":"Watalhin mandood","juz":27,"page":535},{"s":56,"a":30,"key":"56:30","ar":"وَظِلٍّ مَّمْدُودٍ","en":"And shade extended.","tr":"Wathillin mamdood","juz":27,"page":535},{"s":56,"a":31,"key":"56:31","ar":"وَمَآءٍ مَّسْكُوبٍ","en":"And water poured out","tr":"Wama-in maskoob","juz":27,"page":535},{"s":56,"a":32,"key":"56:32","ar":"وَفَـٰكِهَةٍ كَثِيرَةٍ","en":"And fruit, abundant [and varied],","tr":"Wafakihatin katheera","juz":27,"page":535},{"s":56,"a":33,"key":"56:33","ar":"لَّا مَقْطُوعَةٍ وَلَا مَمْنُوعَةٍ","en":"Neither limited [to season] nor forbidden,","tr":"La maqtooAAatin walamamnooAAa","juz":27,"page":535},{"s":56,"a":34,"key":"56:34","ar":"وَفُرُشٍ مَّرْفُوعَةٍ","en":"And [upon] beds raised high.","tr":"Wafurushin marfooAAa","juz":27,"page":535},{"s":56,"a":35,"key":"56:35","ar":"إِنَّآ أَنشَأْنَـٰهُنَّ إِنشَآءً","en":"Indeed, We have produced them [i.e., the women of Paradise] in a [new] creation","tr":"Inna ansha/nahunna inshaa","juz":27,"page":535},{"s":56,"a":36,"key":"56:36","ar":"فَجَعَلْنَـٰهُنَّ أَبْكَارًا","en":"And made them virgins,","tr":"FajaAAalnahunna abkara","juz":27,"page":535},{"s":56,"a":37,"key":"56:37","ar":"عُرُبًا أَتْرَابًا","en":"Devoted [to their husbands] and of equal age,","tr":"AAuruban atraba","juz":27,"page":535},{"s":56,"a":38,"key":"56:38","ar":"لِّأَصْحَـٰبِ ٱلْيَمِينِ","en":"For the companions of the right [who are]","tr":"Li-as-habi alyameen","juz":27,"page":535},{"s":56,"a":39,"key":"56:39","ar":"ثُلَّةٌ مِّنَ ٱلْأَوَّلِينَ","en":"A company of the former peoples","tr":"Thullatun mina al-awwaleen","juz":27,"page":535},{"s":56,"a":40,"key":"56:40","ar":"وَثُلَّةٌ مِّنَ ٱلْـَٔاخِرِينَ","en":"And a company of the later peoples.","tr":"Wathullatun mina al-akhireen","juz":27,"page":535},{"s":56,"a":41,"key":"56:41","ar":"وَأَصْحَـٰبُ ٱلشِّمَالِ مَآ أَصْحَـٰبُ ٱلشِّمَالِ","en":"And the companions of the left - what are the companions of the left?","tr":"Waas-habu ashshimalima as-habu ashshimal","juz":27,"page":535},{"s":56,"a":42,"key":"56:42","ar":"فِى سَمُومٍ وَحَمِيمٍ","en":"[They will be] in scorching fire and scalding water","tr":"Fee samoomin wahameem","juz":27,"page":535},{"s":56,"a":43,"key":"56:43","ar":"وَظِلٍّ مِّن يَحْمُومٍ","en":"And a shade of black smoke,","tr":"Wathillin min yahmoom","juz":27,"page":535},{"s":56,"a":44,"key":"56:44","ar":"لَّا بَارِدٍ وَلَا كَرِيمٍ","en":"Neither cool nor beneficial.","tr":"La baridin wala kareem","juz":27,"page":535},{"s":56,"a":45,"key":"56:45","ar":"إِنَّهُمْ كَانُوا۟ قَبْلَ ذَٰلِكَ مُتْرَفِينَ","en":"Indeed they were, before that, indulging in affluence,","tr":"Innahum kanoo qabla thalikamutrafeen","juz":27,"page":535},{"s":56,"a":46,"key":"56:46","ar":"وَكَانُوا۟ يُصِرُّونَ عَلَى ٱلْحِنثِ ٱلْعَظِيمِ","en":"And they used to persist in the great violation,1","tr":"Wakanoo yusirroona AAalaalhinthi alAAatheem","juz":27,"page":535},{"s":56,"a":47,"key":"56:47","ar":"وَكَانُوا۟ يَقُولُونَ أَئِذَا مِتْنَا وَكُنَّا تُرَابًا وَعِظَـٰمًا أَءِنَّا لَمَبْعُوثُونَ","en":"And they used to say, \"When we die and become dust and bones, are we indeed to be resurrected?","tr":"Wakanoo yaqooloona a-itha mitnawakunna turaban waAAithamana-inna lamabAAoothoon","juz":27,"page":535},{"s":56,"a":48,"key":"56:48","ar":"أَوَءَابَآؤُنَا ٱلْأَوَّلُونَ","en":"And our forefathers [as well]?\"","tr":"Awa abaona al-awwaloon","juz":27,"page":535},{"s":56,"a":49,"key":"56:49","ar":"قُلْ إِنَّ ٱلْأَوَّلِينَ وَٱلْـَٔاخِرِينَ","en":"Say, [O Muḥammad], \"Indeed, the former and later peoples","tr":"Qul inna al-awwaleena wal-akhireen","juz":27,"page":535},{"s":56,"a":50,"key":"56:50","ar":"لَمَجْمُوعُونَ إِلَىٰ مِيقَـٰتِ يَوْمٍ مَّعْلُومٍ","en":"Are to be gathered together for the appointment of a known Day.\"","tr":"LamajmooAAoona ila meeqatiyawmin maAAloom","juz":27,"page":535},{"s":56,"a":51,"key":"56:51","ar":"ثُمَّ إِنَّكُمْ أَيُّهَا ٱلضَّآلُّونَ ٱلْمُكَذِّبُونَ","en":"Then indeed you, O those astray [who are] deniers,","tr":"Thumma innakum ayyuha addalloonaalmukaththiboon","juz":27,"page":536},{"s":56,"a":52,"key":"56:52","ar":"لَـَٔاكِلُونَ مِن شَجَرٍ مِّن زَقُّومٍ","en":"Will be eating from trees of zaqqūm","tr":"Laakiloona min shajarin min zaqqoom","juz":27,"page":536},{"s":56,"a":53,"key":"56:53","ar":"فَمَالِـُٔونَ مِنْهَا ٱلْبُطُونَ","en":"And filling with it your bellies","tr":"Famali-oona minha albutoon","juz":27,"page":536},{"s":56,"a":54,"key":"56:54","ar":"فَشَـٰرِبُونَ عَلَيْهِ مِنَ ٱلْحَمِيمِ","en":"And drinking on top of it from scalding water.","tr":"Fashariboona AAalayhi mina alhameem","juz":27,"page":536},{"s":56,"a":55,"key":"56:55","ar":"فَشَـٰرِبُونَ شُرْبَ ٱلْهِيمِ","en":"And will drink as the drinking of thirsty camels.","tr":"Fashariboona shurba alheem","juz":27,"page":536},{"s":56,"a":56,"key":"56:56","ar":"هَـٰذَا نُزُلُهُمْ يَوْمَ ٱلدِّينِ","en":"That is their accommodation on the Day of Recompense.","tr":"Hatha nuzuluhum yawma addeen","juz":27,"page":536},{"s":56,"a":57,"key":"56:57","ar":"نَحْنُ خَلَقْنَـٰكُمْ فَلَوْلَا تُصَدِّقُونَ","en":"We have created you, so why do you not believe?","tr":"Nahnu khalaqnakum falawlatusaddiqoon","juz":27,"page":536},{"s":56,"a":58,"key":"56:58","ar":"أَفَرَءَيْتُم مَّا تُمْنُونَ","en":"Have you seen that which you emit?1","tr":"Afaraaytum ma tumnoon","juz":27,"page":536},{"s":56,"a":59,"key":"56:59","ar":"ءَأَنتُمْ تَخْلُقُونَهُۥٓ أَمْ نَحْنُ ٱلْخَـٰلِقُونَ","en":"Is it you who creates it, or are We the Creator?","tr":"Aantum takhluqoonahu am nahnu alkhaliqoon","juz":27,"page":536},{"s":56,"a":60,"key":"56:60","ar":"نَحْنُ قَدَّرْنَا بَيْنَكُمُ ٱلْمَوْتَ وَمَا نَحْنُ بِمَسْبُوقِينَ","en":"We have decreed death among you, and We are not to be outdone","tr":"Nahnu qaddarna baynakumualmawta wama nahnu bimasbooqeen","juz":27,"page":536},{"s":56,"a":61,"key":"56:61","ar":"عَلَىٰٓ أَن نُّبَدِّلَ أَمْثَـٰلَكُمْ وَنُنشِئَكُمْ فِى مَا لَا تَعْلَمُونَ","en":"In that We will change your likenesses and produce you in that [form] which you do not know.1","tr":"AAala an nubaddila amthalakumwanunshi-akum fee ma la taAAlamoon","juz":27,"page":536},{"s":56,"a":62,"key":"56:62","ar":"وَلَقَدْ عَلِمْتُمُ ٱلنَّشْأَةَ ٱلْأُولَىٰ فَلَوْلَا تَذَكَّرُونَ","en":"And you have already known the first creation, so will you not remember?","tr":"Walaqad AAalimtumu annash-ata al-oolafalawla tathakkaroon","juz":27,"page":536},{"s":56,"a":63,"key":"56:63","ar":"أَفَرَءَيْتُم مَّا تَحْرُثُونَ","en":"And have you seen that [seed] which you sow?","tr":"Afaraaytum ma tahruthoon","juz":27,"page":536},{"s":56,"a":64,"key":"56:64","ar":"ءَأَنتُمْ تَزْرَعُونَهُۥٓ أَمْ نَحْنُ ٱلزَّٰرِعُونَ","en":"Is it you who makes it grow, or are We the grower?","tr":"Aantum tazraAAoonahu am nahnu azzariAAoon","juz":27,"page":536},{"s":56,"a":65,"key":"56:65","ar":"لَوْ نَشَآءُ لَجَعَلْنَـٰهُ حُطَـٰمًا فَظَلْتُمْ تَفَكَّهُونَ","en":"If We willed, We could make it [dry] debris, and you would remain in wonder,1","tr":"Law nashao lajaAAalnahu hutamanfathaltum tafakkahoon","juz":27,"page":536},{"s":56,"a":66,"key":"56:66","ar":"إِنَّا لَمُغْرَمُونَ","en":"[Saying], \"Indeed, we are [now] in debt;","tr":"Inna lamughramoon","juz":27,"page":536},{"s":56,"a":67,"key":"56:67","ar":"بَلْ نَحْنُ مَحْرُومُونَ","en":"Rather, we have been deprived.\"","tr":"Bal nahnu mahroomoon","juz":27,"page":536},{"s":56,"a":68,"key":"56:68","ar":"أَفَرَءَيْتُمُ ٱلْمَآءَ ٱلَّذِى تَشْرَبُونَ","en":"And have you seen the water that you drink?","tr":"Afaraaytumu almaa allatheetashraboon","juz":27,"page":536},{"s":56,"a":69,"key":"56:69","ar":"ءَأَنتُمْ أَنزَلْتُمُوهُ مِنَ ٱلْمُزْنِ أَمْ نَحْنُ ٱلْمُنزِلُونَ","en":"Is it you who brought it down from the clouds, or is it We who bring it down?","tr":"Aantum anzaltumoohu mina almuzni am nahnualmunziloon","juz":27,"page":536},{"s":56,"a":70,"key":"56:70","ar":"لَوْ نَشَآءُ جَعَلْنَـٰهُ أُجَاجًا فَلَوْلَا تَشْكُرُونَ","en":"If We willed, We could make it bitter, so why are you not grateful?","tr":"Law nashao jaAAalnahu ojajanfalawla tashkuroon","juz":27,"page":536},{"s":56,"a":71,"key":"56:71","ar":"أَفَرَءَيْتُمُ ٱلنَّارَ ٱلَّتِى تُورُونَ","en":"And have you seen the fire that you ignite?","tr":"Afaraaytumu annara allateetooroon","juz":27,"page":536},{"s":56,"a":72,"key":"56:72","ar":"ءَأَنتُمْ أَنشَأْتُمْ شَجَرَتَهَآ أَمْ نَحْنُ ٱلْمُنشِـُٔونَ","en":"Is it you who produced its tree, or are We the producer?","tr":"Aantum ansha/tum shajarataha am nahnualmunshi-oon","juz":27,"page":536},{"s":56,"a":73,"key":"56:73","ar":"نَحْنُ جَعَلْنَـٰهَا تَذْكِرَةً وَمَتَـٰعًا لِّلْمُقْوِينَ","en":"We have made it a reminder1 and provision for the travelers,2","tr":"Nahnu jaAAalnaha tathkiratanwamataAAan lilmuqween","juz":27,"page":536},{"s":56,"a":74,"key":"56:74","ar":"فَسَبِّحْ بِٱسْمِ رَبِّكَ ٱلْعَظِيمِ","en":"So exalt the name of your Lord, the Most Great.","tr":"Fasabbih bismi rabbika alAAatheem","juz":27,"page":536},{"s":56,"a":75,"key":"56:75","ar":"۞ فَلَآ أُقْسِمُ بِمَوَٰقِعِ ٱلنُّجُومِ","en":"Then I swear by the setting of the stars,1","tr":"Fala oqsimu bimawaqiAAi annujoom","juz":27,"page":536},{"s":56,"a":76,"key":"56:76","ar":"وَإِنَّهُۥ لَقَسَمٌ لَّوْ تَعْلَمُونَ عَظِيمٌ","en":"And indeed, it is an oath - if you could know - [most] great.","tr":"Wa-innahu laqasamun law taAAlamoona AAatheem","juz":27,"page":536},{"s":56,"a":77,"key":"56:77","ar":"إِنَّهُۥ لَقُرْءَانٌ كَرِيمٌ","en":"Indeed, it is a noble Qur’ān.","tr":"Innahu laqur-anun kareem","juz":27,"page":537},{"s":56,"a":78,"key":"56:78","ar":"فِى كِتَـٰبٍ مَّكْنُونٍ","en":"In a Register well-protected;1.","tr":"Fee kitabin maknoon","juz":27,"page":537},{"s":56,"a":79,"key":"56:79","ar":"لَّا يَمَسُّهُۥٓ إِلَّا ٱلْمُطَهَّرُونَ","en":"None touch it except the purified [i.e., the angels].","tr":"La yamassuhu illa almutahharoon","juz":27,"page":537},{"s":56,"a":80,"key":"56:80","ar":"تَنزِيلٌ مِّن رَّبِّ ٱلْعَـٰلَمِينَ","en":"[It is] a revelation from the Lord of the worlds.","tr":"Tanzeelun min rabbi alAAalameen","juz":27,"page":537},{"s":56,"a":81,"key":"56:81","ar":"أَفَبِهَـٰذَا ٱلْحَدِيثِ أَنتُم مُّدْهِنُونَ","en":"Then is it to this statement that you are indifferent","tr":"Afabihatha alhadeethi antummudhinoon","juz":27,"page":537},{"s":56,"a":82,"key":"56:82","ar":"وَتَجْعَلُونَ رِزْقَكُمْ أَنَّكُمْ تُكَذِّبُونَ","en":"And make [the thanks for] your provision that you deny [the Provider]?","tr":"WatajAAaloona rizqakum annakum tukaththiboon","juz":27,"page":537},{"s":56,"a":83,"key":"56:83","ar":"فَلَوْلَآ إِذَا بَلَغَتِ ٱلْحُلْقُومَ","en":"Then why, when it [i.e., the soul at death] reaches the throat","tr":"Falawla itha balaghati alhulqoom","juz":27,"page":537},{"s":56,"a":84,"key":"56:84","ar":"وَأَنتُمْ حِينَئِذٍ تَنظُرُونَ","en":"And you are at that time looking on -","tr":"Waantum heena-ithin tanthuroona","juz":27,"page":537},{"s":56,"a":85,"key":"56:85","ar":"وَنَحْنُ أَقْرَبُ إِلَيْهِ مِنكُمْ وَلَـٰكِن لَّا تُبْصِرُونَ","en":"And We [i.e., Our angels] are nearer to him than you, but you do not see -","tr":"Wanahnu aqrabu ilayhi minkum walakinla tubsiroon","juz":27,"page":537},{"s":56,"a":86,"key":"56:86","ar":"فَلَوْلَآ إِن كُنتُمْ غَيْرَ مَدِينِينَ","en":"Then why do you not, if you are not to be recompensed,","tr":"Falawla in kuntum ghayra madeeneen","juz":27,"page":537},{"s":56,"a":87,"key":"56:87","ar":"تَرْجِعُونَهَآ إِن كُنتُمْ صَـٰدِقِينَ","en":"Bring it back,1 if you should be truthful?","tr":"TarjiAAoonaha in kuntum sadiqeen","juz":27,"page":537},{"s":56,"a":88,"key":"56:88","ar":"فَأَمَّآ إِن كَانَ مِنَ ٱلْمُقَرَّبِينَ","en":"And if he [i.e., the deceased] was of those brought near [to Allāh],","tr":"Faamma in kana minaalmuqarrabeen","juz":27,"page":537},{"s":56,"a":89,"key":"56:89","ar":"فَرَوْحٌ وَرَيْحَانٌ وَجَنَّتُ نَعِيمٍ","en":"Then [for him is] rest and bounty and a garden of pleasure.","tr":"Farawhun warayhanun wajannatunaAAeem","juz":27,"page":537},{"s":56,"a":90,"key":"56:90","ar":"وَأَمَّآ إِن كَانَ مِنْ أَصْحَـٰبِ ٱلْيَمِينِ","en":"And if he was of the companions of the right,","tr":"Waamma in kana min as-habialyameen","juz":27,"page":537},{"s":56,"a":91,"key":"56:91","ar":"فَسَلَـٰمٌ لَّكَ مِنْ أَصْحَـٰبِ ٱلْيَمِينِ","en":"Then [the angels will say], \"Peace for you; [you are] from the companions of the right.\"","tr":"Fasalamun laka min as-habialyameen","juz":27,"page":537},{"s":56,"a":92,"key":"56:92","ar":"وَأَمَّآ إِن كَانَ مِنَ ٱلْمُكَذِّبِينَ ٱلضَّآلِّينَ","en":"But if he was of the deniers [who were] astray,","tr":"Waamma in kana mina almukaththibeenaaddalleen","juz":27,"page":537},{"s":56,"a":93,"key":"56:93","ar":"فَنُزُلٌ مِّنْ حَمِيمٍ","en":"Then [for him is] accommodation of scalding water","tr":"Fanuzulun min hameem","juz":27,"page":537},{"s":56,"a":94,"key":"56:94","ar":"وَتَصْلِيَةُ جَحِيمٍ","en":"And burning in Hellfire.","tr":"Watasliyatu jaheem","juz":27,"page":537},{"s":56,"a":95,"key":"56:95","ar":"إِنَّ هَـٰذَا لَهُوَ حَقُّ ٱلْيَقِينِ","en":"Indeed, this is the true certainty,","tr":"Inna hatha lahuwa haqqualyaqeen","juz":27,"page":537},{"s":56,"a":96,"key":"56:96","ar":"فَسَبِّحْ بِٱسْمِ رَبِّكَ ٱلْعَظِيمِ","en":"So exalt the name of your Lord, the Most Great.","tr":"Fasabbih bismi rabbika alAAatheem","juz":27,"page":537},{"s":57,"a":1,"key":"57:1","ar":" سَبَّحَ لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Whatever is in the heavens and earth exalts Allāh,1 and He is the Exalted in Might, the Wise.","tr":"Sabbaha lillahi ma fee assamawatiwal-ardi wahuwa alAAazeezu alhakeem","juz":27,"page":537},{"s":57,"a":2,"key":"57:2","ar":"لَهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ يُحْىِۦ وَيُمِيتُ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"His is the dominion of the heavens and earth. He gives life and causes death, and He is over all things competent.","tr":"Lahu mulku assamawatiwal-ardi yuhyee wayumeetu wahuwa AAalakulli shay-in qadeer","juz":27,"page":537},{"s":57,"a":3,"key":"57:3","ar":"هُوَ ٱلْأَوَّلُ وَٱلْـَٔاخِرُ وَٱلظَّـٰهِرُ وَٱلْبَاطِنُ ۖ وَهُوَ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"He is the First1 and the Last,2 the Ascendant3 and the Intimate,4 and He is, of all things, Knowing.","tr":"Huwa al-awwalu wal-akhiru waththahiruwalbatinu wahuwa bikulli shay-in AAaleem","juz":27,"page":537},{"s":57,"a":4,"key":"57:4","ar":"هُوَ ٱلَّذِى خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ فِى سِتَّةِ أَيَّامٍ ثُمَّ ٱسْتَوَىٰ عَلَى ٱلْعَرْشِ ۚ يَعْلَمُ مَا يَلِجُ فِى ٱلْأَرْضِ وَمَا يَخْرُجُ مِنْهَا وَمَا يَنزِلُ مِنَ ٱلسَّمَآءِ وَمَا يَعْرُجُ فِيهَا ۖ وَهُوَ مَعَكُمْ أَيْنَ مَا كُنتُمْ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"It is He who created the heavens and earth in six days and then established Himself above the Throne.1 He knows what penetrates into the earth and what emerges from it and what descends from the heaven and what ascends therein; and He is with you2 wherever you are. And Allāh, of what you do, is Seeing.","tr":"Huwa allathee khalaqa assamawatiwal-arda fee sittati ayyamin thumma istawaAAala alAAarshi yaAAlamu ma yaliju fee al-ardiwama yakhruju minha wama yanzilu mina assama-iwama yaAAruju feeha wahuwa maAAakum ayna makuntum wallahu bima taAAmaloona baseer","juz":27,"page":538},{"s":57,"a":5,"key":"57:5","ar":"لَّهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَإِلَى ٱللَّهِ تُرْجَعُ ٱلْأُمُورُ","en":"His is the dominion of the heavens and earth. And to Allāh are returned [all] matters.","tr":"Lahu mulku assamawatiwal-ardi wa-ila Allahi turjaAAual-omoor","juz":27,"page":538},{"s":57,"a":6,"key":"57:6","ar":"يُولِجُ ٱلَّيْلَ فِى ٱلنَّهَارِ وَيُولِجُ ٱلنَّهَارَ فِى ٱلَّيْلِ ۚ وَهُوَ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"He causes the night to enter the day and causes the day to enter the night, and He is Knowing of that within the breasts.","tr":"Yooliju allayla fee annahariwayooliju annahara fee allayi wahuwa AAaleemun bithatiassudoor","juz":27,"page":538},{"s":57,"a":7,"key":"57:7","ar":"ءَامِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَأَنفِقُوا۟ مِمَّا جَعَلَكُم مُّسْتَخْلَفِينَ فِيهِ ۖ فَٱلَّذِينَ ءَامَنُوا۟ مِنكُمْ وَأَنفَقُوا۟ لَهُمْ أَجْرٌ كَبِيرٌ","en":"Believe in Allāh and His Messenger and spend out of that in which He has made you successive inheritors. For those who have believed among you and spent,1 there will be a great reward.","tr":"Aminoo billahiwarasoolihi waanfiqoo mimma jaAAalakum mustakhlafeenafeehi fallatheena amanoo minkum waanfaqoolahum ajrun kabeer","juz":27,"page":538},{"s":57,"a":8,"key":"57:8","ar":"وَمَا لَكُمْ لَا تُؤْمِنُونَ بِٱللَّهِ ۙ وَٱلرَّسُولُ يَدْعُوكُمْ لِتُؤْمِنُوا۟ بِرَبِّكُمْ وَقَدْ أَخَذَ مِيثَـٰقَكُمْ إِن كُنتُم مُّؤْمِنِينَ","en":"And why do you not believe in Allāh while the Messenger invites you to believe in your Lord and He has taken your covenant, if you should [truly] be believers?","tr":"Wama lakum la tu/minoona billahiwarrasoolu yadAAookum litu/minoo birabbikum waqad akhathameethaqakum in kuntum mu/mineen","juz":27,"page":538},{"s":57,"a":9,"key":"57:9","ar":"هُوَ ٱلَّذِى يُنَزِّلُ عَلَىٰ عَبْدِهِۦٓ ءَايَـٰتٍۭ بَيِّنَـٰتٍ لِّيُخْرِجَكُم مِّنَ ٱلظُّلُمَـٰتِ إِلَى ٱلنُّورِ ۚ وَإِنَّ ٱللَّهَ بِكُمْ لَرَءُوفٌ رَّحِيمٌ","en":"It is He who sends down upon His Servant [Muḥammad (ﷺ)] verses of clear evidence that He may bring you out from darknesses into the light. And indeed, Allāh is to you Kind and Merciful.","tr":"Huwa allathee yunazzilu AAalaAAabdihi ayatin bayyinatin liyukhrijakummina aththulumati ila annooriwa-inna Allaha bikum laraoofun raheem","juz":27,"page":538},{"s":57,"a":10,"key":"57:10","ar":"وَمَا لَكُمْ أَلَّا تُنفِقُوا۟ فِى سَبِيلِ ٱللَّهِ وَلِلَّهِ مِيرَٰثُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ لَا يَسْتَوِى مِنكُم مَّنْ أَنفَقَ مِن قَبْلِ ٱلْفَتْحِ وَقَـٰتَلَ ۚ أُو۟لَـٰٓئِكَ أَعْظَمُ دَرَجَةً مِّنَ ٱلَّذِينَ أَنفَقُوا۟ مِنۢ بَعْدُ وَقَـٰتَلُوا۟ ۚ وَكُلًّا وَعَدَ ٱللَّهُ ٱلْحُسْنَىٰ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌ","en":"And why do you not spend in the cause of Allāh while to Allāh belongs the heritage of the heavens and the earth? Not equal among you are those who spent before the conquest [of Makkah] and fought [and those who did so after it]. Those are greater in degree than they who spent afterwards and fought. But to all Allāh has promised the best [reward]. And Allāh, of what you do, is Aware.","tr":"Wama lakum alla tunfiqoo feesabeeli Allahi walillahi meerathu assamawatiwal-ardi la yastawee minkum man anfaqa minqabli alfathi waqatala ola-ika aAAthamudarajatan mina allatheena anfaqoo min baAAdu waqataloowakullan waAAada Allahu alhusna wallahubima taAAmaloona khabeer","juz":27,"page":538},{"s":57,"a":11,"key":"57:11","ar":"مَّن ذَا ٱلَّذِى يُقْرِضُ ٱللَّهَ قَرْضًا حَسَنًا فَيُضَـٰعِفَهُۥ لَهُۥ وَلَهُۥٓ أَجْرٌ كَرِيمٌ","en":"Who is it that would loan Allāh a goodly loan so He will multiply it for him and he will have a noble reward?","tr":"Man tha allathee yuqriduAllaha qardan hasanan fayudaAAifahulahu walahu ajrun kareem","juz":27,"page":538},{"s":57,"a":12,"key":"57:12","ar":"يَوْمَ تَرَى ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَـٰتِ يَسْعَىٰ نُورُهُم بَيْنَ أَيْدِيهِمْ وَبِأَيْمَـٰنِهِم بُشْرَىٰكُمُ ٱلْيَوْمَ جَنَّـٰتٌ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا ۚ ذَٰلِكَ هُوَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"On the Day you see the believing men and believing women, their light proceeding before them and on their right, [it will be said], \"Your good tidings today are [of] gardens beneath which rivers flow, wherein you will abide eternally.\" That is what is the great attainment.","tr":"Yawma tara almu/mineena walmu/minatiyasAAa nooruhum bayna aydeehim wabi-aymanihim bushrakumualyawma jannatun tajree min tahtiha al-anharukhalideena feeha thalika huwa alfawzu alAAatheem","juz":27,"page":539},{"s":57,"a":13,"key":"57:13","ar":"يَوْمَ يَقُولُ ٱلْمُنَـٰفِقُونَ وَٱلْمُنَـٰفِقَـٰتُ لِلَّذِينَ ءَامَنُوا۟ ٱنظُرُونَا نَقْتَبِسْ مِن نُّورِكُمْ قِيلَ ٱرْجِعُوا۟ وَرَآءَكُمْ فَٱلْتَمِسُوا۟ نُورًا فَضُرِبَ بَيْنَهُم بِسُورٍ لَّهُۥ بَابٌۢ بَاطِنُهُۥ فِيهِ ٱلرَّحْمَةُ وَظَـٰهِرُهُۥ مِن قِبَلِهِ ٱلْعَذَابُ","en":"On the [same] Day the hypocrite men and hypocrite women will say to those who believed, \"Wait for us that we may acquire some of your light.\" It will be said, \"Go back behind you1 and seek light.\" And a wall will be placed between them with a door, its interior containing mercy, but on the outside of it is torment.","tr":"Yawma yaqoolu almunafiqoona walmunafiqatulillatheena amanoo onthuroonanaqtabis min noorikum qeela irjiAAoo waraakum faltamisoonooran faduriba baynahum bisoorin lahu babun batinuhufeehi arrahmatu wathahiruhumin qibalihi alAAathab","juz":27,"page":539},{"s":57,"a":14,"key":"57:14","ar":"يُنَادُونَهُمْ أَلَمْ نَكُن مَّعَكُمْ ۖ قَالُوا۟ بَلَىٰ وَلَـٰكِنَّكُمْ فَتَنتُمْ أَنفُسَكُمْ وَتَرَبَّصْتُمْ وَٱرْتَبْتُمْ وَغَرَّتْكُمُ ٱلْأَمَانِىُّ حَتَّىٰ جَآءَ أَمْرُ ٱللَّهِ وَغَرَّكُم بِٱللَّهِ ٱلْغَرُورُ","en":"They [i.e., the hypocrites] will call to them [i.e., the believers], \"Were we not with you?\" They will say, \"Yes, but you afflicted yourselves1 and awaited [misfortune for us] and doubted, and wishful thinking deluded you until there came the command of Allāh. And the Deceiver [i.e., Satan] deceived you concerning Allāh.","tr":"Yunadoonahum alam nakun maAAakum qaloobala walakinnakum fatantum anfusakum watarabbastumwartabtum wagharratkumu al-amaniyyu hattajaa amru Allahi wagharrakum billahialgharoor","juz":27,"page":539},{"s":57,"a":15,"key":"57:15","ar":"فَٱلْيَوْمَ لَا يُؤْخَذُ مِنكُمْ فِدْيَةٌ وَلَا مِنَ ٱلَّذِينَ كَفَرُوا۟ ۚ مَأْوَىٰكُمُ ٱلنَّارُ ۖ هِىَ مَوْلَىٰكُمْ ۖ وَبِئْسَ ٱلْمَصِيرُ","en":"So today no ransom will be taken from you or from those who disbelieved. Your refuge is the Fire. It is most worthy of you, and wretched is the destination.\"","tr":"Falyawma la yu/khathuminkum fidyatun wala mina allatheena kafaroo ma/wakumuannaru hiya mawlakum wabi/sa almaseer","juz":27,"page":539},{"s":57,"a":16,"key":"57:16","ar":"۞ أَلَمْ يَأْنِ لِلَّذِينَ ءَامَنُوٓا۟ أَن تَخْشَعَ قُلُوبُهُمْ لِذِكْرِ ٱللَّهِ وَمَا نَزَلَ مِنَ ٱلْحَقِّ وَلَا يَكُونُوا۟ كَٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ مِن قَبْلُ فَطَالَ عَلَيْهِمُ ٱلْأَمَدُ فَقَسَتْ قُلُوبُهُمْ ۖ وَكَثِيرٌ مِّنْهُمْ فَـٰسِقُونَ","en":"Has the time not come for those who have believed that their hearts should become humbly submissive at the remembrance of Allāh and what has come down of the truth? And let them not be like those who were given the Scripture before, and a long period passed over them, so their hearts hardened; and many of them are defiantly disobedient.","tr":"Alam ya/ni lillatheena amanooan takhshaAAa quloobuhum lithikri Allahi wamanazala mina alhaqqi wala yakoonoo kallatheenaootoo alkitaba min qablu fatala AAalayhimu al-amadufaqasat quloobuhum wakatheerun minhum fasiqoon","juz":27,"page":539},{"s":57,"a":17,"key":"57:17","ar":"ٱعْلَمُوٓا۟ أَنَّ ٱللَّهَ يُحْىِ ٱلْأَرْضَ بَعْدَ مَوْتِهَا ۚ قَدْ بَيَّنَّا لَكُمُ ٱلْـَٔايَـٰتِ لَعَلَّكُمْ تَعْقِلُونَ","en":"Know that Allāh gives life to the earth after its lifelessness. We have made clear to you the signs; perhaps you will understand.1","tr":"IAAlamoo anna Allaha yuhyeeal-arda baAAda mawtiha qad bayyanna lakumual-ayati laAAallakum taAAqiloon","juz":27,"page":539},{"s":57,"a":18,"key":"57:18","ar":"إِنَّ ٱلْمُصَّدِّقِينَ وَٱلْمُصَّدِّقَـٰتِ وَأَقْرَضُوا۟ ٱللَّهَ قَرْضًا حَسَنًا يُضَـٰعَفُ لَهُمْ وَلَهُمْ أَجْرٌ كَرِيمٌ","en":"Indeed, the men who practice charity and the women who practice charity and [they who] have loaned Allāh a goodly loan - it will be multiplied for them, and they will have a noble reward.","tr":"Inna almussaddiqeena walmussaddiqatiwaaqradoo Allaha qardan hasanan yudaAAafulahum walahum ajrun kareem","juz":27,"page":539},{"s":57,"a":19,"key":"57:19","ar":"وَٱلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرُسُلِهِۦٓ أُو۟لَـٰٓئِكَ هُمُ ٱلصِّدِّيقُونَ ۖ وَٱلشُّهَدَآءُ عِندَ رَبِّهِمْ لَهُمْ أَجْرُهُمْ وَنُورُهُمْ ۖ وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَـٰتِنَآ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْجَحِيمِ","en":"And those who have believed in Allāh and His messengers - those are [in the ranks of] the supporters of truth and the martyrs, with their Lord. For them is their reward and their light.1 But those who have disbelieved and denied Our verses - those are the companions of Hellfire.","tr":"Wallatheena amanoo billahiwarusulihi ola-ika humu assiddeeqoona washshuhadaoAAinda rabbihim lahum ajruhum wanooruhum wallatheenakafaroo wakaththaboo bi-ayatina ola-ikaas-habu aljaheem","juz":27,"page":540},{"s":57,"a":20,"key":"57:20","ar":"ٱعْلَمُوٓا۟ أَنَّمَا ٱلْحَيَوٰةُ ٱلدُّنْيَا لَعِبٌ وَلَهْوٌ وَزِينَةٌ وَتَفَاخُرٌۢ بَيْنَكُمْ وَتَكَاثُرٌ فِى ٱلْأَمْوَٰلِ وَٱلْأَوْلَـٰدِ ۖ كَمَثَلِ غَيْثٍ أَعْجَبَ ٱلْكُفَّارَ نَبَاتُهُۥ ثُمَّ يَهِيجُ فَتَرَىٰهُ مُصْفَرًّا ثُمَّ يَكُونُ حُطَـٰمًا ۖ وَفِى ٱلْـَٔاخِرَةِ عَذَابٌ شَدِيدٌ وَمَغْفِرَةٌ مِّنَ ٱللَّهِ وَرِضْوَٰنٌ ۚ وَمَا ٱلْحَيَوٰةُ ٱلدُّنْيَآ إِلَّا مَتَـٰعُ ٱلْغُرُورِ","en":"Know that the life of this world is but amusement and diversion and adornment and boasting to one another and competition in increase of wealth and children - like the example of a rain whose [resulting] plant growth pleases the tillers; then it dries and you see it turned yellow; then it becomes [scattered] debris. And in the Hereafter is severe punishment and forgiveness from Allāh and approval. And what is the worldly life except the enjoyment of delusion.","tr":"IAAlamoo annama alhayatuaddunya laAAibun walahwun wazeenatun watafakhurunbaynakum watakathurun fee al-amwali wal-awladikamathali ghaythin aAAjaba alkuffara nabatuhuthumma yaheeju fatarahu musfarran thumma yakoonu hutamanwafee al-akhirati AAathabun shadeedun wamaghfiratunmina Allahi waridwanun wama alhayatuaddunya illa mataAAu alghuroor","juz":27,"page":540},{"s":57,"a":21,"key":"57:21","ar":"سَابِقُوٓا۟ إِلَىٰ مَغْفِرَةٍ مِّن رَّبِّكُمْ وَجَنَّةٍ عَرْضُهَا كَعَرْضِ ٱلسَّمَآءِ وَٱلْأَرْضِ أُعِدَّتْ لِلَّذِينَ ءَامَنُوا۟ بِٱللَّهِ وَرُسُلِهِۦ ۚ ذَٰلِكَ فَضْلُ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ","en":"Race [i.e., compete] toward forgiveness from your Lord and a Garden whose width is like the width of the heavens and earth, prepared for those who believed in Allāh and His messengers. That is the bounty of Allāh which He gives to whom He wills, and Allāh is the possessor of great bounty.","tr":"Sabiqoo ila maghfiratin minrabbikum wajannatin AAarduha kaAAardi assama-iwal-ardi oAAiddat lillatheena amanoobillahi warusulihi thalika fadlu Allahiyu/teehi man yashao wallahu thooalfadli alAAatheem","juz":27,"page":540},{"s":57,"a":22,"key":"57:22","ar":"مَآ أَصَابَ مِن مُّصِيبَةٍ فِى ٱلْأَرْضِ وَلَا فِىٓ أَنفُسِكُمْ إِلَّا فِى كِتَـٰبٍ مِّن قَبْلِ أَن نَّبْرَأَهَآ ۚ إِنَّ ذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌ","en":"No disaster strikes upon the earth or among yourselves except that it is in a register1 before We bring it into being - indeed that, for Allāh, is easy -","tr":"Ma asaba min museebatinfee al-ardi wala fee anfusikum illa fee kitabinmin qabli an nabraaha inna thalika AAala Allahiyaseer","juz":27,"page":540},{"s":57,"a":23,"key":"57:23","ar":"لِّكَيْلَا تَأْسَوْا۟ عَلَىٰ مَا فَاتَكُمْ وَلَا تَفْرَحُوا۟ بِمَآ ءَاتَىٰكُمْ ۗ وَٱللَّهُ لَا يُحِبُّ كُلَّ مُخْتَالٍ فَخُورٍ","en":"In order that you not despair over what has eluded you and not exult [in pride] over what He has given you. And Allāh does not like everyone self-deluded and boastful -","tr":"Likayla ta/saw AAala mafatakum wala tafrahoo bima atakumwallahu la yuhibbu kulla mukhtalinfakhoor","juz":27,"page":540},{"s":57,"a":24,"key":"57:24","ar":"ٱلَّذِينَ يَبْخَلُونَ وَيَأْمُرُونَ ٱلنَّاسَ بِٱلْبُخْلِ ۗ وَمَن يَتَوَلَّ فَإِنَّ ٱللَّهَ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ","en":"[Those] who are stingy and enjoin upon people stinginess. And whoever turns away1 - then indeed, Allāh is the Free of need, the Praiseworthy.","tr":"Allatheena yabkhaloona waya/muroona annasabilbukhli waman yatawalla fa-inna Allaha huwaalghaniyyu alhameed","juz":27,"page":540},{"s":57,"a":25,"key":"57:25","ar":"لَقَدْ أَرْسَلْنَا رُسُلَنَا بِٱلْبَيِّنَـٰتِ وَأَنزَلْنَا مَعَهُمُ ٱلْكِتَـٰبَ وَٱلْمِيزَانَ لِيَقُومَ ٱلنَّاسُ بِٱلْقِسْطِ ۖ وَأَنزَلْنَا ٱلْحَدِيدَ فِيهِ بَأْسٌ شَدِيدٌ وَمَنَـٰفِعُ لِلنَّاسِ وَلِيَعْلَمَ ٱللَّهُ مَن يَنصُرُهُۥ وَرُسُلَهُۥ بِٱلْغَيْبِ ۚ إِنَّ ٱللَّهَ قَوِىٌّ عَزِيزٌ","en":"We have already sent Our messengers with clear evidences and sent down with them the Scripture and the balance that the people may maintain [their affairs] in justice. And We sent down iron, wherein is great military might and benefits for the people, and so that Allāh may make evident those who support Him and His messengers unseen. Indeed, Allāh is Powerful and Exalted in Might.","tr":"Laqad arsalna rusulana bilbayyinatiwaanzalna maAAahumu alkitaba walmeezanaliyaqooma annasu bilqisti waanzalnaalhadeeda feehi ba/sun shadeedun wamanafiAAu linnasiwaliyaAAlama Allahu man yansuruhu warusulahu bilghaybiinna Allaha qawiyyun AAazeez","juz":27,"page":541},{"s":57,"a":26,"key":"57:26","ar":"وَلَقَدْ أَرْسَلْنَا نُوحًا وَإِبْرَٰهِيمَ وَجَعَلْنَا فِى ذُرِّيَّتِهِمَا ٱلنُّبُوَّةَ وَٱلْكِتَـٰبَ ۖ فَمِنْهُم مُّهْتَدٍ ۖ وَكَثِيرٌ مِّنْهُمْ فَـٰسِقُونَ","en":"And We have already sent Noah and Abraham and placed in their descendants prophethood and scripture; and among them is he who is guided, but many of them are defiantly disobedient.","tr":"Walaqad arsalna noohan wa-ibraheemawajaAAalna fee thurriyyatihima annubuwwatawalkitaba faminhum muhtadin wakatheerun minhum fasiqoon","juz":27,"page":541},{"s":57,"a":27,"key":"57:27","ar":"ثُمَّ قَفَّيْنَا عَلَىٰٓ ءَاثَـٰرِهِم بِرُسُلِنَا وَقَفَّيْنَا بِعِيسَى ٱبْنِ مَرْيَمَ وَءَاتَيْنَـٰهُ ٱلْإِنجِيلَ وَجَعَلْنَا فِى قُلُوبِ ٱلَّذِينَ ٱتَّبَعُوهُ رَأْفَةً وَرَحْمَةً وَرَهْبَانِيَّةً ٱبْتَدَعُوهَا مَا كَتَبْنَـٰهَا عَلَيْهِمْ إِلَّا ٱبْتِغَآءَ رِضْوَٰنِ ٱللَّهِ فَمَا رَعَوْهَا حَقَّ رِعَايَتِهَا ۖ فَـَٔاتَيْنَا ٱلَّذِينَ ءَامَنُوا۟ مِنْهُمْ أَجْرَهُمْ ۖ وَكَثِيرٌ مِّنْهُمْ فَـٰسِقُونَ","en":"Then We sent following their footsteps [i.e., traditions] Our messengers and followed [them] with Jesus, the son of Mary, and gave him the Gospel. And We placed in the hearts of those who followed him compassion and mercy and monasticism, which they innovated; We did not prescribe it for them except [that they did so] seeking the approval of Allāh. But they did not observe it with due observance. So We gave the ones who believed among them their reward, but many of them are defiantly disobedient.","tr":"Thumma qaffayna AAala atharihimbirusulina waqaffayna biAAeesa ibni maryamawaataynahu al-injeela wajaAAalna fee quloobiallatheena ittabaAAoohu ra/fatan warahmatan warahbaniyyatanibtadaAAooha ma katabnaha AAalayhimilla ibtighaa ridwani Allahifama raAAawha haqqa riAAayatihafaatayna allatheena amanoo minhumajrahum wakatheerun minhum fasiqoon","juz":27,"page":541},{"s":57,"a":28,"key":"57:28","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَءَامِنُوا۟ بِرَسُولِهِۦ يُؤْتِكُمْ كِفْلَيْنِ مِن رَّحْمَتِهِۦ وَيَجْعَل لَّكُمْ نُورًا تَمْشُونَ بِهِۦ وَيَغْفِرْ لَكُمْ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"O you who have believed, fear Allāh and believe in His Messenger; He will [then] give you a double portion of His mercy and make for you a light by which you will walk and forgive you; and Allāh is Forgiving and Merciful.","tr":"Ya ayyuha allatheena amanooittaqoo Allaha waaminoo birasoolihi yu/tikumkiflayni min rahmatihi wayajAAal lakum nooran tamshoonabihi wayaghfir lakum wallahu ghafoorun raheem","juz":27,"page":541},{"s":57,"a":29,"key":"57:29","ar":"لِّئَلَّا يَعْلَمَ أَهْلُ ٱلْكِتَـٰبِ أَلَّا يَقْدِرُونَ عَلَىٰ شَىْءٍ مِّن فَضْلِ ٱللَّهِ ۙ وَأَنَّ ٱلْفَضْلَ بِيَدِ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ","en":"[This is] so that the People of the Scripture may know that they are not able [to obtain] anything from the bounty of Allāh1 and that [all] bounty is in the hand2 of Allāh; He gives it to whom He wills. And Allāh is the possessor of great bounty.","tr":"Li-alla yaAAlama ahlu alkitabialla yaqdiroona AAala shay-in min fadli Allahiwaanna alfadla biyadi Allahi yu/teehi man yashaowallahu thoo alfadli alAAatheem","juz":27,"page":541},{"s":58,"a":1,"key":"58:1","ar":" قَدْ سَمِعَ ٱللَّهُ قَوْلَ ٱلَّتِى تُجَـٰدِلُكَ فِى زَوْجِهَا وَتَشْتَكِىٓ إِلَى ٱللَّهِ وَٱللَّهُ يَسْمَعُ تَحَاوُرَكُمَآ ۚ إِنَّ ٱللَّهَ سَمِيعٌۢ بَصِيرٌ","en":"Certainly has Allāh heard the speech of the one who argues [i.e., pleads] with you, [O Muḥammad], concerning her husband and directs her complaint to Allāh. And Allāh hears your dialogue; indeed, Allāh is Hearing and Seeing.","tr":"Qad samiAAa Allahu qawla allatee tujadilukafee zawjiha watashtakee ila Allahi wallahuyasmaAAu tahawurakuma inna Allaha sameeAAunbaseer","juz":28,"page":542},{"s":58,"a":2,"key":"58:2","ar":"ٱلَّذِينَ يُظَـٰهِرُونَ مِنكُم مِّن نِّسَآئِهِم مَّا هُنَّ أُمَّهَـٰتِهِمْ ۖ إِنْ أُمَّهَـٰتُهُمْ إِلَّا ٱلَّـٰٓـِٔى وَلَدْنَهُمْ ۚ وَإِنَّهُمْ لَيَقُولُونَ مُنكَرًا مِّنَ ٱلْقَوْلِ وَزُورًا ۚ وَإِنَّ ٱللَّهَ لَعَفُوٌّ غَفُورٌ","en":"Those who pronounce ẓihār1 among you [to separate] from their wives - they are not [consequently] their mothers. Their mothers are none but those who gave birth to them. And indeed, they are saying an objectionable statement and a falsehood. But indeed, Allāh is Pardoning and Forgiving.","tr":"Allatheena yuthahiroonaminkum min nisa-ihim ma hunna ommahatihim inommahatuhum illa alla-ee waladnahumwa-innahum layaqooloona munkaran mina alqawli wazooran wa-innaAllaha laAAafuwwun ghafoor","juz":28,"page":542},{"s":58,"a":3,"key":"58:3","ar":"وَٱلَّذِينَ يُظَـٰهِرُونَ مِن نِّسَآئِهِمْ ثُمَّ يَعُودُونَ لِمَا قَالُوا۟ فَتَحْرِيرُ رَقَبَةٍ مِّن قَبْلِ أَن يَتَمَآسَّا ۚ ذَٰلِكُمْ تُوعَظُونَ بِهِۦ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌ","en":"And those who pronounce ẓihār from their wives and then [wish to] go back on what they said - then [there must be] the freeing of a slave before they touch one another. That is what you are admonished thereby; and Allāh is Aware of what you do.","tr":"Wallatheena yuthahiroonamin nisa-ihim thumma yaAAoodoona lima qaloofatahreeru raqabatin min qabli an yatamassa thalikumtooAAathoona bihi wallahu bimataAAmaloona khabeer","juz":28,"page":542},{"s":58,"a":4,"key":"58:4","ar":"فَمَن لَّمْ يَجِدْ فَصِيَامُ شَهْرَيْنِ مُتَتَابِعَيْنِ مِن قَبْلِ أَن يَتَمَآسَّا ۖ فَمَن لَّمْ يَسْتَطِعْ فَإِطْعَامُ سِتِّينَ مِسْكِينًا ۚ ذَٰلِكَ لِتُؤْمِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ ۚ وَتِلْكَ حُدُودُ ٱللَّهِ ۗ وَلِلْكَـٰفِرِينَ عَذَابٌ أَلِيمٌ","en":"And he who does not find [a slave] - then a fast for two months consecutively1 before they touch one another; and he who is unable - then the feeding of sixty poor persons. That is for you to believe [completely] in Allāh and His Messenger; and those are the limits [set by] Allāh. And for the disbelievers is a painful punishment.","tr":"Faman lam yajid fasiyamushahrayni mutatabiAAayni min qabli an yatamassafaman lam yastatiAA fa-itAAamu sitteenamiskeenan thalika litu/minoo billahiwarasoolihi watilka hudoodu Allahi walilkafireenaAAathabun aleem","juz":28,"page":542},{"s":58,"a":5,"key":"58:5","ar":"إِنَّ ٱلَّذِينَ يُحَآدُّونَ ٱللَّهَ وَرَسُولَهُۥ كُبِتُوا۟ كَمَا كُبِتَ ٱلَّذِينَ مِن قَبْلِهِمْ ۚ وَقَدْ أَنزَلْنَآ ءَايَـٰتٍۭ بَيِّنَـٰتٍ ۚ وَلِلْكَـٰفِرِينَ عَذَابٌ مُّهِينٌ","en":"Indeed, those who oppose Allāh and His Messenger are abased as those before them were abased. And We have certainly sent down verses of clear evidence. And for the disbelievers is a humiliating punishment","tr":"Inna allatheena yuhaddoona Allahawarasoolahu kubitoo kama kubita allatheena minqablihim waqad anzalna ayatin bayyinatinwalilkafireena AAathabun muheen","juz":28,"page":542},{"s":58,"a":6,"key":"58:6","ar":"يَوْمَ يَبْعَثُهُمُ ٱللَّهُ جَمِيعًا فَيُنَبِّئُهُم بِمَا عَمِلُوٓا۟ ۚ أَحْصَىٰهُ ٱللَّهُ وَنَسُوهُ ۚ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ شَهِيدٌ","en":"On the Day when Allāh will resurrect them all and inform them of what they did. Allāh had enumerated it, while they forgot it; and Allāh is, over all things, Witness.1","tr":"Yawma yabAAathuhumu Allahu jameeAAanfayunabbi-ohum bima AAamiloo ahsahu Allahuwanasoohu wallahu AAala kulli shay-inshaheed","juz":28,"page":542},{"s":58,"a":7,"key":"58:7","ar":"أَلَمْ تَرَ أَنَّ ٱللَّهَ يَعْلَمُ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ مَا يَكُونُ مِن نَّجْوَىٰ ثَلَـٰثَةٍ إِلَّا هُوَ رَابِعُهُمْ وَلَا خَمْسَةٍ إِلَّا هُوَ سَادِسُهُمْ وَلَآ أَدْنَىٰ مِن ذَٰلِكَ وَلَآ أَكْثَرَ إِلَّا هُوَ مَعَهُمْ أَيْنَ مَا كَانُوا۟ ۖ ثُمَّ يُنَبِّئُهُم بِمَا عَمِلُوا۟ يَوْمَ ٱلْقِيَـٰمَةِ ۚ إِنَّ ٱللَّهَ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"Have you not considered that Allāh knows what is in the heavens and what is on the earth? There are not three in a private conversation but that He is the fourth of them,1 nor are there five but that He is the sixth of them - and no less than that and no more except that He is with them [in knowledge] wherever they are. Then He will inform them of what they did, on the Day of Resurrection. Indeed Allāh is, of all things, Knowing.","tr":"Alam tara anna Allaha yaAAlamu mafee assamawati wama fee al-ardima yakoonu min najwa thalathatin illahuwa rabiAAuhum wala khamsatin illa huwa sadisuhumwala adna min thalika wala aktharailla huwa maAAahum ayna ma kanoo thummayunabbi-ohum bima AAamiloo yawma alqiyamati innaAllaha bikulli shay-in AAaleem","juz":28,"page":543},{"s":58,"a":8,"key":"58:8","ar":"أَلَمْ تَرَ إِلَى ٱلَّذِينَ نُهُوا۟ عَنِ ٱلنَّجْوَىٰ ثُمَّ يَعُودُونَ لِمَا نُهُوا۟ عَنْهُ وَيَتَنَـٰجَوْنَ بِٱلْإِثْمِ وَٱلْعُدْوَٰنِ وَمَعْصِيَتِ ٱلرَّسُولِ وَإِذَا جَآءُوكَ حَيَّوْكَ بِمَا لَمْ يُحَيِّكَ بِهِ ٱللَّهُ وَيَقُولُونَ فِىٓ أَنفُسِهِمْ لَوْلَا يُعَذِّبُنَا ٱللَّهُ بِمَا نَقُولُ ۚ حَسْبُهُمْ جَهَنَّمُ يَصْلَوْنَهَا ۖ فَبِئْسَ ٱلْمَصِيرُ","en":"Have you not considered those who were forbidden from private conversation [i.e., ridicule and conspiracy] and then return to that which they were forbidden and converse among themselves about sin and aggression and disobedience to the Messenger? And when they come to you, they greet you with that [word] by which Allāh does not greet you1 and say among themselves, \"Why does Allāh not punish us for what we say?\" Sufficient for them is Hell, which they will [enter to] burn, and wretched is the destination.","tr":"Alam tara ila allatheena nuhooAAani annajwa thumma yaAAoodoona lima nuhooAAanhu wayatanajawna bil-ithmi walAAudwaniwamaAAsiyati arrasooli wa-itha jaookahayyawka bima lam yuhayyika bihi Allahuwayaqooloona fee anfusihim lawla yuAAaththibunaAllahu bima naqoolu hasbuhum jahannamu yaslawnahafabi/sa almaseer","juz":28,"page":543},{"s":58,"a":9,"key":"58:9","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا تَنَـٰجَيْتُمْ فَلَا تَتَنَـٰجَوْا۟ بِٱلْإِثْمِ وَٱلْعُدْوَٰنِ وَمَعْصِيَتِ ٱلرَّسُولِ وَتَنَـٰجَوْا۟ بِٱلْبِرِّ وَٱلتَّقْوَىٰ ۖ وَٱتَّقُوا۟ ٱللَّهَ ٱلَّذِىٓ إِلَيْهِ تُحْشَرُونَ","en":"O you who have believed, when you converse privately, do not converse about sin and aggression and disobedience to the Messenger but converse about righteousness and piety. And fear Allāh, to whom you will be gathered.","tr":"Ya ayyuha allatheena amanooitha tanajaytum fala tatanajaw bil-ithmiwalAAudwani wamaAAsiyati arrasooliwatanajaw bilbirri wattaqwa wattaqooAllaha allathee ilayhi tuhsharoon","juz":28,"page":543},{"s":58,"a":10,"key":"58:10","ar":"إِنَّمَا ٱلنَّجْوَىٰ مِنَ ٱلشَّيْطَـٰنِ لِيَحْزُنَ ٱلَّذِينَ ءَامَنُوا۟ وَلَيْسَ بِضَآرِّهِمْ شَيْـًٔا إِلَّا بِإِذْنِ ٱللَّهِ ۚ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ","en":"Private conversation is only from Satan that he may grieve those who have believed,1 but he will not harm them at all except by permission of Allāh. And upon Allāh let the believers rely.","tr":"Innama annajwa mina ashshaytaniliyahzuna allatheena amanoo walaysa bidarrihimshay-an illa bi-ithni Allahi waAAalaAllahi falyatawakkali almu/minoon","juz":28,"page":543},{"s":58,"a":11,"key":"58:11","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا قِيلَ لَكُمْ تَفَسَّحُوا۟ فِى ٱلْمَجَـٰلِسِ فَٱفْسَحُوا۟ يَفْسَحِ ٱللَّهُ لَكُمْ ۖ وَإِذَا قِيلَ ٱنشُزُوا۟ فَٱنشُزُوا۟ يَرْفَعِ ٱللَّهُ ٱلَّذِينَ ءَامَنُوا۟ مِنكُمْ وَٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ دَرَجَـٰتٍ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌ","en":"O you who have believed, when you are told, \"Space yourselves\" in assemblies, then make space; Allāh will make space for you.1 And when you are told, \"Arise,\"2 then arise; Allāh will raise those who have believed among you and those who were given knowledge, by degrees. And Allāh is Aware of what you do.","tr":"Ya ayyuha allatheena amanooitha qeela lakum tafassahoo fee almajalisifafsahoo yafsahi Allahu lakum wa-ithaqeela onshuzoo fanshuzoo yarfaAAi Allahu allatheenaamanoo minkum wallatheena ootoo alAAilmadarajatin wallahu bima taAAmaloonakhabeer","juz":28,"page":543},{"s":58,"a":12,"key":"58:12","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا نَـٰجَيْتُمُ ٱلرَّسُولَ فَقَدِّمُوا۟ بَيْنَ يَدَىْ نَجْوَىٰكُمْ صَدَقَةً ۚ ذَٰلِكَ خَيْرٌ لَّكُمْ وَأَطْهَرُ ۚ فَإِن لَّمْ تَجِدُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"O you who have believed, when you [wish to] privately consult the Messenger, present before your consultation a charity. That is better for you and purer. But if you find not [the means] - then indeed, Allāh is Forgiving and Merciful.","tr":"Ya ayyuha allatheena amanooitha najaytumu arrasoola faqaddimoo baynayaday najwakum sadaqatan thalika khayrunlakum waatharu fa-in lam tajidoo fa-inna Allahaghafoorun raheem","juz":28,"page":544},{"s":58,"a":13,"key":"58:13","ar":"ءَأَشْفَقْتُمْ أَن تُقَدِّمُوا۟ بَيْنَ يَدَىْ نَجْوَىٰكُمْ صَدَقَـٰتٍ ۚ فَإِذْ لَمْ تَفْعَلُوا۟ وَتَابَ ٱللَّهُ عَلَيْكُمْ فَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَأَطِيعُوا۟ ٱللَّهَ وَرَسُولَهُۥ ۚ وَٱللَّهُ خَبِيرٌۢ بِمَا تَعْمَلُونَ","en":"Have you feared to present before your consultation charities? Then when you do not and Allāh has forgiven you, then [at least] establish prayer and give zakāh and obey Allāh and His Messenger. And Allāh is Aware of what you do.","tr":"Aashfaqtum an tuqaddimoo bayna yaday najwakumsadaqatin fa-ith lam tafAAaloo watabaAllahu AAalaykum faaqeemoo assalatawaatoo azzakata waateeAAoo Allahawarasoolahu wallahu khabeerun bimataAAmaloon","juz":28,"page":544},{"s":58,"a":14,"key":"58:14","ar":"۞ أَلَمْ تَرَ إِلَى ٱلَّذِينَ تَوَلَّوْا۟ قَوْمًا غَضِبَ ٱللَّهُ عَلَيْهِم مَّا هُم مِّنكُمْ وَلَا مِنْهُمْ وَيَحْلِفُونَ عَلَى ٱلْكَذِبِ وَهُمْ يَعْلَمُونَ","en":"Have you not considered those who make allies of a people with whom Allāh has become angry? They are neither of you nor of them, and they swear to untruth while they know [they are lying].","tr":"Alam tara ila allatheenatawallaw qawman ghadiba Allahu AAalayhim mahum minkum wala minhum wayahlifoona AAalaalkathibi wahum yaAAlamoon","juz":28,"page":544},{"s":58,"a":15,"key":"58:15","ar":"أَعَدَّ ٱللَّهُ لَهُمْ عَذَابًا شَدِيدًا ۖ إِنَّهُمْ سَآءَ مَا كَانُوا۟ يَعْمَلُونَ","en":"Allāh has prepared for them a severe punishment. Indeed, it was evil that they were doing.","tr":"aAAadda Allahu lahum AAathabanshadeedan innahum saa ma kanoo yaAAmaloon","juz":28,"page":544},{"s":58,"a":16,"key":"58:16","ar":"ٱتَّخَذُوٓا۟ أَيْمَـٰنَهُمْ جُنَّةً فَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ فَلَهُمْ عَذَابٌ مُّهِينٌ","en":"They took their [false] oaths as a cover, so they averted [people] from the way of Allāh, and for them is a humiliating punishment.","tr":"Ittakhathoo aymanahum junnatanfasaddoo AAan sabeeli Allahi falahum AAathabunmuheen","juz":28,"page":544},{"s":58,"a":17,"key":"58:17","ar":"لَّن تُغْنِىَ عَنْهُمْ أَمْوَٰلُهُمْ وَلَآ أَوْلَـٰدُهُم مِّنَ ٱللَّهِ شَيْـًٔا ۚ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ ۖ هُمْ فِيهَا خَـٰلِدُونَ","en":"Never will their wealth or their children avail them against Allāh at all. Those are the companions of the Fire; they will abide therein eternally","tr":"Lan tughniya AAanhum amwaluhum walaawladuhum mina Allahi shay-an ola-ika as-habuannari hum feeha khalidoon","juz":28,"page":544},{"s":58,"a":18,"key":"58:18","ar":"يَوْمَ يَبْعَثُهُمُ ٱللَّهُ جَمِيعًا فَيَحْلِفُونَ لَهُۥ كَمَا يَحْلِفُونَ لَكُمْ ۖ وَيَحْسَبُونَ أَنَّهُمْ عَلَىٰ شَىْءٍ ۚ أَلَآ إِنَّهُمْ هُمُ ٱلْكَـٰذِبُونَ","en":"On the Day Allāh will resurrect them all, and they will swear to Him as they swear to you and think that they are [standing] on something.1 Unquestionably, it is they who are the liars.","tr":"Yawma yabAAathuhumu Allahu jameeAAanfayahlifoona lahu kama yahlifoona lakum wayahsaboonaannahum AAala shay-in ala innahum humu alkathiboon","juz":28,"page":544},{"s":58,"a":19,"key":"58:19","ar":"ٱسْتَحْوَذَ عَلَيْهِمُ ٱلشَّيْطَـٰنُ فَأَنسَىٰهُمْ ذِكْرَ ٱللَّهِ ۚ أُو۟لَـٰٓئِكَ حِزْبُ ٱلشَّيْطَـٰنِ ۚ أَلَآ إِنَّ حِزْبَ ٱلشَّيْطَـٰنِ هُمُ ٱلْخَـٰسِرُونَ","en":"Satan has overcome them and made them forget the remembrance of Allāh. Those are the party of Satan. Unquestionably, the party of Satan - they will be the losers.","tr":"Istahwatha AAalayhimu ashshaytanufaansahum thikra Allahi ola-ika hizbuashshaytani ala inna hizba ashshaytanihumu alkhasiroon","juz":28,"page":544},{"s":58,"a":20,"key":"58:20","ar":"إِنَّ ٱلَّذِينَ يُحَآدُّونَ ٱللَّهَ وَرَسُولَهُۥٓ أُو۟لَـٰٓئِكَ فِى ٱلْأَذَلِّينَ","en":"Indeed, the ones who oppose Allāh and His Messenger - those will be among the most humbled.","tr":"Inna allatheena yuhaddoona Allahawarasoolahu ola-ika fee al-athalleen","juz":28,"page":544},{"s":58,"a":21,"key":"58:21","ar":"كَتَبَ ٱللَّهُ لَأَغْلِبَنَّ أَنَا۠ وَرُسُلِىٓ ۚ إِنَّ ٱللَّهَ قَوِىٌّ عَزِيزٌ","en":"Allāh has written [i.e., decreed], \"I will surely overcome, I and My messengers.\" Indeed, Allāh is Powerful and Exalted in Might.","tr":"Kataba Allahu laaghlibanna anawarusulee inna Allaha qawiyyun AAazeez","juz":28,"page":544},{"s":58,"a":22,"key":"58:22","ar":"لَّا تَجِدُ قَوْمًا يُؤْمِنُونَ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ يُوَآدُّونَ مَنْ حَآدَّ ٱللَّهَ وَرَسُولَهُۥ وَلَوْ كَانُوٓا۟ ءَابَآءَهُمْ أَوْ أَبْنَآءَهُمْ أَوْ إِخْوَٰنَهُمْ أَوْ عَشِيرَتَهُمْ ۚ أُو۟لَـٰٓئِكَ كَتَبَ فِى قُلُوبِهِمُ ٱلْإِيمَـٰنَ وَأَيَّدَهُم بِرُوحٍ مِّنْهُ ۖ وَيُدْخِلُهُمْ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَا ۚ رَضِىَ ٱللَّهُ عَنْهُمْ وَرَضُوا۟ عَنْهُ ۚ أُو۟لَـٰٓئِكَ حِزْبُ ٱللَّهِ ۚ أَلَآ إِنَّ حِزْبَ ٱللَّهِ هُمُ ٱلْمُفْلِحُونَ","en":"You will not find a people who believe in Allāh and the Last Day having affection for those who oppose Allāh and His Messenger, even if they were their fathers or their sons or their brothers or their kindred. Those - He has decreed within their hearts faith and supported them with spirit1 from Him. And We will admit them to gardens beneath which rivers flow, wherein they abide eternally. Allāh is pleased with them, and they are pleased with Him - those are the party of Allāh. Unquestionably, the party of Allāh - they are the successful.","tr":"La tajidu qawman yu/minoona billahiwalyawmi al-akhiri yuwaddoona man haddaAllaha warasoolahu walaw kanoo abaahumaw abnaahum aw ikhwanahum aw AAasheeratahum ola-ikakataba fee quloobihimu al-eemana waayyadahum biroohinminhu wayudkhiluhum jannatin tajree min tahtihaal-anharu khalideena feeha radiya AllahuAAanhum waradoo AAanhu ola-ika hizbu Allahiala inna hizba Allahi humu almuflihoon","juz":28,"page":545},{"s":59,"a":1,"key":"59:1","ar":" سَبَّحَ لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Whatever is in the heavens and whatever is on the earth exalts Allāh,1 and He is the Exalted in Might, the Wise.","tr":"Sabbaha lillahi ma fee assamawatiwama fee al-ardi wahuwa alAAazeezu alhakeem","juz":28,"page":545},{"s":59,"a":2,"key":"59:2","ar":"هُوَ ٱلَّذِىٓ أَخْرَجَ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَـٰبِ مِن دِيَـٰرِهِمْ لِأَوَّلِ ٱلْحَشْرِ ۚ مَا ظَنَنتُمْ أَن يَخْرُجُوا۟ ۖ وَظَنُّوٓا۟ أَنَّهُم مَّانِعَتُهُمْ حُصُونُهُم مِّنَ ٱللَّهِ فَأَتَىٰهُمُ ٱللَّهُ مِنْ حَيْثُ لَمْ يَحْتَسِبُوا۟ ۖ وَقَذَفَ فِى قُلُوبِهِمُ ٱلرُّعْبَ ۚ يُخْرِبُونَ بُيُوتَهُم بِأَيْدِيهِمْ وَأَيْدِى ٱلْمُؤْمِنِينَ فَٱعْتَبِرُوا۟ يَـٰٓأُو۟لِى ٱلْأَبْصَـٰرِ","en":"It is He who expelled the ones who disbelieved among the People of the Scripture1 from their homes at the first gathering.2 You did not think they would leave, and they thought that their fortresses would protect them from Allāh; but [the decree of] Allāh came upon them from where they had not expected, and He cast terror into their hearts [so] they destroyed their houses by their [own] hands and the hands of the believers. So take warning, O people of vision.","tr":"Huwa allathee akhraja allatheenakafaroo min ahli alkitabi min diyarihim li-awwalialhashri ma thanantum an yakhrujoo wathannooannahum maniAAatuhum husoonuhum mina Allahifaatahumu Allahu min haythu lam yahtasiboowaqathafa fee quloobihimu arruAAba yukhriboonabuyootahum bi-aydeehim waaydee almu/mineena faAAtabiroo yaolee al-absar","juz":28,"page":545},{"s":59,"a":3,"key":"59:3","ar":"وَلَوْلَآ أَن كَتَبَ ٱللَّهُ عَلَيْهِمُ ٱلْجَلَآءَ لَعَذَّبَهُمْ فِى ٱلدُّنْيَا ۖ وَلَهُمْ فِى ٱلْـَٔاخِرَةِ عَذَابُ ٱلنَّارِ","en":"And if not that Allāh had decreed for them evacuation, He would have punished them in [this] world, and for them in the Hereafter is the punishment of the Fire.","tr":"Walawla an kataba AllahuAAalayhimu aljalaa laAAaththabahum fee addunyawalahum fee al-akhirati AAathabu annar","juz":28,"page":545},{"s":59,"a":4,"key":"59:4","ar":"ذَٰلِكَ بِأَنَّهُمْ شَآقُّوا۟ ٱللَّهَ وَرَسُولَهُۥ ۖ وَمَن يُشَآقِّ ٱللَّهَ فَإِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ","en":"That is because they opposed Allāh and His Messenger. And whoever opposes Allāh - then indeed, Allāh is severe in penalty.","tr":"Thalika bi-annahum shaqqoo Allahawarasoolahu waman yushaqqi Allaha fa-inna Allahashadeedu alAAiqab","juz":28,"page":546},{"s":59,"a":5,"key":"59:5","ar":"مَا قَطَعْتُم مِّن لِّينَةٍ أَوْ تَرَكْتُمُوهَا قَآئِمَةً عَلَىٰٓ أُصُولِهَا فَبِإِذْنِ ٱللَّهِ وَلِيُخْزِىَ ٱلْفَـٰسِقِينَ","en":"Whatever you have cut down of [their] palm trees or left standing on their trunks - it was by permission of Allāh and so He would disgrace the defiantly disobedient.","tr":"Ma qataAAtum min leenatin awtaraktumooha qa-imatan AAala osoolihafabi-ithni Allahi waliyukhziya alfasiqeen","juz":28,"page":546},{"s":59,"a":6,"key":"59:6","ar":"وَمَآ أَفَآءَ ٱللَّهُ عَلَىٰ رَسُولِهِۦ مِنْهُمْ فَمَآ أَوْجَفْتُمْ عَلَيْهِ مِنْ خَيْلٍ وَلَا رِكَابٍ وَلَـٰكِنَّ ٱللَّهَ يُسَلِّطُ رُسُلَهُۥ عَلَىٰ مَن يَشَآءُ ۚ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"And what Allāh restored [of property] to His Messenger from them - you did not spur for it [in an expedition] any horses or camels,1 but Allāh gives His messengers power over whom He wills, and Allāh is over all things competent.","tr":"Wama afaa Allahu AAalarasoolihi minhum fama awjaftum AAalayhi min khaylin walarikabin walakinna Allaha yusalliturusulahu AAala man yashao wallahuAAala kulli shay-in qadeer","juz":28,"page":546},{"s":59,"a":7,"key":"59:7","ar":"مَّآ أَفَآءَ ٱللَّهُ عَلَىٰ رَسُولِهِۦ مِنْ أَهْلِ ٱلْقُرَىٰ فَلِلَّهِ وَلِلرَّسُولِ وَلِذِى ٱلْقُرْبَىٰ وَٱلْيَتَـٰمَىٰ وَٱلْمَسَـٰكِينِ وَٱبْنِ ٱلسَّبِيلِ كَىْ لَا يَكُونَ دُولَةًۢ بَيْنَ ٱلْأَغْنِيَآءِ مِنكُمْ ۚ وَمَآ ءَاتَىٰكُمُ ٱلرَّسُولُ فَخُذُوهُ وَمَا نَهَىٰكُمْ عَنْهُ فَٱنتَهُوا۟ ۚ وَٱتَّقُوا۟ ٱللَّهَ ۖ إِنَّ ٱللَّهَ شَدِيدُ ٱلْعِقَابِ","en":"And what Allāh restored to His Messenger from the people of the towns - it is for Allāh and for the Messenger and for [his] near relatives1 and orphans and the needy and the [stranded] traveler2 - so that it will not be a perpetual distribution among the rich from among you. And whatever the Messenger has given you - take; and what he has forbidden you - refrain from. And fear Allāh; indeed, Allāh is severe in penalty.","tr":"Ma afaa Allahu AAalarasoolihi min ahli alqura falillahi walirrasooliwalithee alqurba walyatama walmasakeeniwabni assabeeli kay la yakoona doolatanbayna al-aghniya-i minkum wama atakumuarrasoolu fakhuthoohu wama nahakumAAanhu fantahoo wattaqoo Allaha inna Allahashadeedu alAAiqab","juz":28,"page":546},{"s":59,"a":8,"key":"59:8","ar":"لِلْفُقَرَآءِ ٱلْمُهَـٰجِرِينَ ٱلَّذِينَ أُخْرِجُوا۟ مِن دِيَـٰرِهِمْ وَأَمْوَٰلِهِمْ يَبْتَغُونَ فَضْلًا مِّنَ ٱللَّهِ وَرِضْوَٰنًا وَيَنصُرُونَ ٱللَّهَ وَرَسُولَهُۥٓ ۚ أُو۟لَـٰٓئِكَ هُمُ ٱلصَّـٰدِقُونَ","en":"For the poor emigrants who were expelled from their homes and their properties, seeking bounty from Allāh and [His] approval and supporting [the cause of] Allāh and His Messenger, [there is also a share]. Those are the truthful.","tr":"Lilfuqara-i almuhajireena allatheenaokhrijoo min diyarihim waamwalihim yabtaghoona fadlanmina Allahi waridwanan wayansuroonaAllaha warasoolahu ola-ika humu assadiqoon","juz":28,"page":546},{"s":59,"a":9,"key":"59:9","ar":"وَٱلَّذِينَ تَبَوَّءُو ٱلدَّارَ وَٱلْإِيمَـٰنَ مِن قَبْلِهِمْ يُحِبُّونَ مَنْ هَاجَرَ إِلَيْهِمْ وَلَا يَجِدُونَ فِى صُدُورِهِمْ حَاجَةً مِّمَّآ أُوتُوا۟ وَيُؤْثِرُونَ عَلَىٰٓ أَنفُسِهِمْ وَلَوْ كَانَ بِهِمْ خَصَاصَةٌ ۚ وَمَن يُوقَ شُحَّ نَفْسِهِۦ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"And [also for] those who were settled in the Home [i.e.,al-Madīnah] and [adopted] the faith before them.1 They love those who emigrated to them and find not any want in their breasts of what they [i.e., the emigrants] were given but give [them] preference over themselves, even though they are in privation. And whoever is protected from the stinginess of his soul - it is those who will be the successful.","tr":"Wallatheena tabawwaoo addarawal-eemana min qablihim yuhibboona man hajarailayhim wala yajidoona fee sudoorihim hajatanmimma ootoo wayu/thiroona AAala anfusihim walaw kanabihim khasasatun waman yooqa shuhha nafsihi faola-ikahumu almuflihoon","juz":28,"page":546},{"s":59,"a":10,"key":"59:10","ar":"وَٱلَّذِينَ جَآءُو مِنۢ بَعْدِهِمْ يَقُولُونَ رَبَّنَا ٱغْفِرْ لَنَا وَلِإِخْوَٰنِنَا ٱلَّذِينَ سَبَقُونَا بِٱلْإِيمَـٰنِ وَلَا تَجْعَلْ فِى قُلُوبِنَا غِلًّا لِّلَّذِينَ ءَامَنُوا۟ رَبَّنَآ إِنَّكَ رَءُوفٌ رَّحِيمٌ","en":"And [there is a share for] those who come after them, saying, \"Our Lord, forgive us and our brothers who preceded us in faith and put not in our hearts [any] resentment toward those who have believed. Our Lord, indeed You are Kind and Merciful.\"","tr":"Wallatheena jaoo minbaAAdihim yaqooloona rabbana ighfir lana wali-ikhwaninaallatheena sabaqoona bil-eemani walatajAAal fee quloobina ghillan lillatheena amanoorabbana innaka raoofun raheem","juz":28,"page":547},{"s":59,"a":11,"key":"59:11","ar":"۞ أَلَمْ تَرَ إِلَى ٱلَّذِينَ نَافَقُوا۟ يَقُولُونَ لِإِخْوَٰنِهِمُ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَـٰبِ لَئِنْ أُخْرِجْتُمْ لَنَخْرُجَنَّ مَعَكُمْ وَلَا نُطِيعُ فِيكُمْ أَحَدًا أَبَدًا وَإِن قُوتِلْتُمْ لَنَنصُرَنَّكُمْ وَٱللَّهُ يَشْهَدُ إِنَّهُمْ لَكَـٰذِبُونَ","en":"Have you not considered those who practice hypocrisy, saying to their brothers [i.e., associates] who have disbelieved among the People of the Scripture, \"If you are expelled, we will surely leave with you, and we will not obey, in regard to you, anyone - ever; and if you are fought, we will surely aid you.\" But Allāh testifies that they are liars.","tr":"Alam tara ila allatheena nafaqooyaqooloona li-ikhwanihimu allatheena kafaroo minahli alkitabi la-in okhrijtum lanakhrujanna maAAakum walanuteeAAu feekum ahadan abadan wa-in qootiltum lanansurannakumwallahu yashhadu innahum lakathiboon","juz":28,"page":547},{"s":59,"a":12,"key":"59:12","ar":"لَئِنْ أُخْرِجُوا۟ لَا يَخْرُجُونَ مَعَهُمْ وَلَئِن قُوتِلُوا۟ لَا يَنصُرُونَهُمْ وَلَئِن نَّصَرُوهُمْ لَيُوَلُّنَّ ٱلْأَدْبَـٰرَ ثُمَّ لَا يُنصَرُونَ","en":"If they are expelled, they will not leave with them, and if they are fought, they will not aid them. And [even] if they should aid them, they will surely turn their backs; then [thereafter] they will not be aided.","tr":"La-in okhrijoo la yakhrujoonamaAAahum wala-in qootiloo la yansuroonahum wala-innasaroohum layuwallunna al-adbara thumma layunsaroon","juz":28,"page":547},{"s":59,"a":13,"key":"59:13","ar":"لَأَنتُمْ أَشَدُّ رَهْبَةً فِى صُدُورِهِم مِّنَ ٱللَّهِ ۚ ذَٰلِكَ بِأَنَّهُمْ قَوْمٌ لَّا يَفْقَهُونَ","en":"You [believers] are more fearful within their breasts than Allāh. That is because they are a people who do not understand.","tr":"Laantum ashaddu rahbatan fee sudoorihimmina Allahi thalika bi-annahum qawmun layafqahoon","juz":28,"page":547},{"s":59,"a":14,"key":"59:14","ar":"لَا يُقَـٰتِلُونَكُمْ جَمِيعًا إِلَّا فِى قُرًى مُّحَصَّنَةٍ أَوْ مِن وَرَآءِ جُدُرٍۭ ۚ بَأْسُهُم بَيْنَهُمْ شَدِيدٌ ۚ تَحْسَبُهُمْ جَمِيعًا وَقُلُوبُهُمْ شَتَّىٰ ۚ ذَٰلِكَ بِأَنَّهُمْ قَوْمٌ لَّا يَعْقِلُونَ","en":"They will not fight you all except within fortified cities or from behind walls. Their violence [i.e., enmity] among themselves is severe. You think they are together, but their hearts are diverse. That is because they are a people who do not reason.","tr":"La yuqatiloonakum jameeAAanilla fee quran muhassanatin aw min wara-ijudurin ba/suhum baynahum shadeedun tahsabuhum jameeAAanwaquloobuhum shatta thalika bi-annahum qawmun layaAAqiloon","juz":28,"page":547},{"s":59,"a":15,"key":"59:15","ar":"كَمَثَلِ ٱلَّذِينَ مِن قَبْلِهِمْ قَرِيبًا ۖ ذَاقُوا۟ وَبَالَ أَمْرِهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"[Theirs is] like the example of those shortly before them: they tasted the bad consequence of their affair, and they will have a painful punishment.","tr":"Kamathali allatheena min qablihimqareeban thaqoo wabala amrihim walahum AAathabunaleem","juz":28,"page":547},{"s":59,"a":16,"key":"59:16","ar":"كَمَثَلِ ٱلشَّيْطَـٰنِ إِذْ قَالَ لِلْإِنسَـٰنِ ٱكْفُرْ فَلَمَّا كَفَرَ قَالَ إِنِّى بَرِىٓءٌ مِّنكَ إِنِّىٓ أَخَافُ ٱللَّهَ رَبَّ ٱلْعَـٰلَمِينَ","en":"[The hypocrites are] like the example of Satan when he says to man, \"Disbelieve.\" But when he disbelieves, he says, \"Indeed, I am disassociated from you. Indeed, I fear Allāh, Lord of the worlds.\"","tr":"Kamathali ashshaytani ithqala lil-insani okfur falamma kafara qalainnee baree-on minka innee akhafu Allaha rabba alAAalameen","juz":28,"page":547},{"s":59,"a":17,"key":"59:17","ar":"فَكَانَ عَـٰقِبَتَهُمَآ أَنَّهُمَا فِى ٱلنَّارِ خَـٰلِدَيْنِ فِيهَا ۚ وَذَٰلِكَ جَزَٰٓؤُا۟ ٱلظَّـٰلِمِينَ","en":"So the outcome for both of them is that they will be in the Fire, abiding eternally therein. And that is the recompense of the wrongdoers.","tr":"Fakana AAaqibatahumaannahuma fee annari khalidayni feehawathalika jazao aththalimeen","juz":28,"page":548},{"s":59,"a":18,"key":"59:18","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ ٱتَّقُوا۟ ٱللَّهَ وَلْتَنظُرْ نَفْسٌ مَّا قَدَّمَتْ لِغَدٍ ۖ وَٱتَّقُوا۟ ٱللَّهَ ۚ إِنَّ ٱللَّهَ خَبِيرٌۢ بِمَا تَعْمَلُونَ","en":"O you who have believed, fear Allāh. And let every soul look to what it has put forth for tomorrow - and fear Allāh. Indeed, Allāh is Aware of what you do.","tr":"Ya ayyuha allatheena amanooittaqoo Allaha waltanthur nafsun maqaddamat lighadin wattaqoo Allaha inna Allahakhabeerun bima taAAmaloon","juz":28,"page":548},{"s":59,"a":19,"key":"59:19","ar":"وَلَا تَكُونُوا۟ كَٱلَّذِينَ نَسُوا۟ ٱللَّهَ فَأَنسَىٰهُمْ أَنفُسَهُمْ ۚ أُو۟لَـٰٓئِكَ هُمُ ٱلْفَـٰسِقُونَ","en":"And be not like those who forgot Allāh, so He made them forget themselves. Those are the defiantly disobedient.","tr":"Wala takoonoo kallatheenanasoo Allaha faansahum anfusahum ola-ikahumu alfasiqoon","juz":28,"page":548},{"s":59,"a":20,"key":"59:20","ar":"لَا يَسْتَوِىٓ أَصْحَـٰبُ ٱلنَّارِ وَأَصْحَـٰبُ ٱلْجَنَّةِ ۚ أَصْحَـٰبُ ٱلْجَنَّةِ هُمُ ٱلْفَآئِزُونَ","en":"Not equal are the companions of the Fire and the companions of Paradise. The companions of Paradise - they are the attainers [of success].","tr":"La yastawee as-habu annariwaas-habu aljannati as-habu aljannatihumu alfa-izoon","juz":28,"page":548},{"s":59,"a":21,"key":"59:21","ar":"لَوْ أَنزَلْنَا هَـٰذَا ٱلْقُرْءَانَ عَلَىٰ جَبَلٍ لَّرَأَيْتَهُۥ خَـٰشِعًا مُّتَصَدِّعًا مِّنْ خَشْيَةِ ٱللَّهِ ۚ وَتِلْكَ ٱلْأَمْثَـٰلُ نَضْرِبُهَا لِلنَّاسِ لَعَلَّهُمْ يَتَفَكَّرُونَ","en":"If We had sent down this Qur’ān upon a mountain, you would have seen it humbled and splitting from fear of Allāh. And these examples We present to the people that perhaps they will give thought.","tr":"Law anzalna hatha alqur-anaAAala jabalin laraaytahu khashiAAan mutasaddiAAanmin khashyati Allahi watilka al-amthalu nadribuhalinnasi laAAallahum yatafakkaroon","juz":28,"page":548},{"s":59,"a":22,"key":"59:22","ar":"هُوَ ٱللَّهُ ٱلَّذِى لَآ إِلَـٰهَ إِلَّا هُوَ ۖ عَـٰلِمُ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ ۖ هُوَ ٱلرَّحْمَـٰنُ ٱلرَّحِيمُ","en":"He is Allāh, other than whom there is no deity, Knower of the unseen and the witnessed.1 He is the Entirely Merciful, the Especially Merciful.","tr":"Huwa Allahu allathee lailaha illa huwa AAalimu alghaybi washshahadatihuwa arrahmanu arraheem","juz":28,"page":548},{"s":59,"a":23,"key":"59:23","ar":"هُوَ ٱللَّهُ ٱلَّذِى لَآ إِلَـٰهَ إِلَّا هُوَ ٱلْمَلِكُ ٱلْقُدُّوسُ ٱلسَّلَـٰمُ ٱلْمُؤْمِنُ ٱلْمُهَيْمِنُ ٱلْعَزِيزُ ٱلْجَبَّارُ ٱلْمُتَكَبِّرُ ۚ سُبْحَـٰنَ ٱللَّهِ عَمَّا يُشْرِكُونَ","en":"He is Allāh, other than whom there is no deity, the Sovereign,1 the Pure,2 the Perfection,3 the Grantor of Security,4 the Overseer,5 the Exalted in Might,6 the Compeller,7 the Superior.8 Exalted is Allāh above whatever they associate with Him.","tr":"Huwa Allahu allathee lailaha illa huwa almaliku alquddoosu assalamualmu/minu almuhayminu alAAazeezu aljabbaru almutakabbirusubhana Allahi AAamma yushrikoon","juz":28,"page":548},{"s":59,"a":24,"key":"59:24","ar":"هُوَ ٱللَّهُ ٱلْخَـٰلِقُ ٱلْبَارِئُ ٱلْمُصَوِّرُ ۖ لَهُ ٱلْأَسْمَآءُ ٱلْحُسْنَىٰ ۚ يُسَبِّحُ لَهُۥ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"He is Allāh, the Creator,1 the Producer,2 the Fashioner;3 to Him belong the best names.4 Whatever is in the heavens and earth is exalting Him. And He is the Exalted in Might, the Wise.5","tr":"Huwa Allahu alkhaliqu albari-oalmusawwiru lahu al-asmao alhusnayusabbihu lahu ma fee assamawatiwal-ardi wahuwa alAAazeezu alhakeem","juz":28,"page":548},{"s":60,"a":1,"key":"60:1","ar":" يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَّخِذُوا۟ عَدُوِّى وَعَدُوَّكُمْ أَوْلِيَآءَ تُلْقُونَ إِلَيْهِم بِٱلْمَوَدَّةِ وَقَدْ كَفَرُوا۟ بِمَا جَآءَكُم مِّنَ ٱلْحَقِّ يُخْرِجُونَ ٱلرَّسُولَ وَإِيَّاكُمْ ۙ أَن تُؤْمِنُوا۟ بِٱللَّهِ رَبِّكُمْ إِن كُنتُمْ خَرَجْتُمْ جِهَـٰدًا فِى سَبِيلِى وَٱبْتِغَآءَ مَرْضَاتِى ۚ تُسِرُّونَ إِلَيْهِم بِٱلْمَوَدَّةِ وَأَنَا۠ أَعْلَمُ بِمَآ أَخْفَيْتُمْ وَمَآ أَعْلَنتُمْ ۚ وَمَن يَفْعَلْهُ مِنكُمْ فَقَدْ ضَلَّ سَوَآءَ ٱلسَّبِيلِ","en":"O you who have believed, do not take My enemies and your enemies as allies,1 extending to them affection while they have disbelieved in what came to you of the truth, having driven out the Prophet and yourselves [only] because you believe in Allāh, your Lord. If you have come out for jihād [i.e., fighting or striving] in My cause and seeking means to My approval, [take them not as friends]. You confide to them affection [i.e., instruction], but I am most knowing of what you have concealed and what you have declared. And whoever does it among you has certainly strayed from the soundness of the way.","tr":"Ya ayyuha allatheena amanoola tattakhithoo AAaduwwee waAAaduwwakum awliyaatulqoona ilayhim bilmawaddati waqad kafaroo bima jaakummina alhaqqi yukhrijoona arrasoola wa-iyyakuman tu/minoo billahi rabbikum in kuntum kharajtumjihadan fee sabeelee wabtighaa mardateetusirroona ilayhim bilmawaddati waana aAAlamu bimaakhfaytum wama aAAlantum waman yafAAalhu minkum faqad dallasawaa assabeel","juz":28,"page":549},{"s":60,"a":2,"key":"60:2","ar":"إِن يَثْقَفُوكُمْ يَكُونُوا۟ لَكُمْ أَعْدَآءً وَيَبْسُطُوٓا۟ إِلَيْكُمْ أَيْدِيَهُمْ وَأَلْسِنَتَهُم بِٱلسُّوٓءِ وَوَدُّوا۟ لَوْ تَكْفُرُونَ","en":"If they gain dominance over you, they would be [i.e., behave] to you as enemies and extend against you their hands and their tongues with evil, and they wish you would disbelieve.","tr":"In yathqafookum yakoonoo lakam aAAdaanwayabsutoo ilaykum aydiyahum waalsinatahum bissoo-iwawaddoo law takfuroon","juz":28,"page":549},{"s":60,"a":3,"key":"60:3","ar":"لَن تَنفَعَكُمْ أَرْحَامُكُمْ وَلَآ أَوْلَـٰدُكُمْ ۚ يَوْمَ ٱلْقِيَـٰمَةِ يَفْصِلُ بَيْنَكُمْ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"Never will your relatives or your children benefit you; the Day of Resurrection He will judge between you. And Allāh, of what you do, is Seeing.","tr":"Lan tanfaAAakum arhamukum walaawladukum yawma alqiyamati yafsilu baynakumwallahu bima taAAmaloona baseer","juz":28,"page":549},{"s":60,"a":4,"key":"60:4","ar":"قَدْ كَانَتْ لَكُمْ أُسْوَةٌ حَسَنَةٌ فِىٓ إِبْرَٰهِيمَ وَٱلَّذِينَ مَعَهُۥٓ إِذْ قَالُوا۟ لِقَوْمِهِمْ إِنَّا بُرَءَٰٓؤُا۟ مِنكُمْ وَمِمَّا تَعْبُدُونَ مِن دُونِ ٱللَّهِ كَفَرْنَا بِكُمْ وَبَدَا بَيْنَنَا وَبَيْنَكُمُ ٱلْعَدَٰوَةُ وَٱلْبَغْضَآءُ أَبَدًا حَتَّىٰ تُؤْمِنُوا۟ بِٱللَّهِ وَحْدَهُۥٓ إِلَّا قَوْلَ إِبْرَٰهِيمَ لِأَبِيهِ لَأَسْتَغْفِرَنَّ لَكَ وَمَآ أَمْلِكُ لَكَ مِنَ ٱللَّهِ مِن شَىْءٍ ۖ رَّبَّنَا عَلَيْكَ تَوَكَّلْنَا وَإِلَيْكَ أَنَبْنَا وَإِلَيْكَ ٱلْمَصِيرُ","en":"There has already been for you an excellent pattern1 in Abraham and those with him, when they said to their people, \"Indeed, we are disassociated from you and from whatever you worship other than Allāh. We have denied you, and there has appeared between us and you animosity and hatred forever until you believe in Allāh alone\" - except for the saying of Abraham to his father, \"I will surely ask forgiveness for you, but I have not [power to do] for you anything against Allāh. Our Lord, upon You we have relied, and to You we have returned, and to You is the destination.","tr":"Qad kanat lakum oswatun hasanatunfee ibraheema wallatheena maAAahu ithqaloo liqawmihim inna buraao minkum wamimmataAAbudoona min dooni Allahi kafarna bikum wabadabaynana wabaynakumu alAAadawatu walbaghdaoabadan hatta tu/minoo billahi wahdahuilla qawla ibraheema li-abeehi laastaghfiranna lakawama amliku laka mina Allahi min shay-in rabbanaAAalayka tawakkalna wa-ilayka anabna wa-ilayka almaseer","juz":28,"page":549},{"s":60,"a":5,"key":"60:5","ar":"رَبَّنَا لَا تَجْعَلْنَا فِتْنَةً لِّلَّذِينَ كَفَرُوا۟ وَٱغْفِرْ لَنَا رَبَّنَآ ۖ إِنَّكَ أَنتَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Our Lord, make us not [objects of] torment for the disbelievers and forgive us, our Lord. Indeed, it is You who is the Exalted in Might, the Wise.\"","tr":"Rabbana la tajAAalnafitnatan lillatheena kafaroo waghfir lanarabbana innaka anta alAAazeezu alhakeem","juz":28,"page":549},{"s":60,"a":6,"key":"60:6","ar":"لَقَدْ كَانَ لَكُمْ فِيهِمْ أُسْوَةٌ حَسَنَةٌ لِّمَن كَانَ يَرْجُوا۟ ٱللَّهَ وَٱلْيَوْمَ ٱلْـَٔاخِرَ ۚ وَمَن يَتَوَلَّ فَإِنَّ ٱللَّهَ هُوَ ٱلْغَنِىُّ ٱلْحَمِيدُ","en":"There has certainly been for you in them an excellent pattern for anyone whose hope is in Allāh and the Last Day. And whoever turns away - then indeed, Allāh is the Free of need, the Praiseworthy.","tr":"Laqad kana lakum feehim oswatun hasanatunliman kana yarjoo Allaha walyawma al-akhirawaman yatawalla fa-inna Allaha huwa alghanniyyu alhameed","juz":28,"page":550},{"s":60,"a":7,"key":"60:7","ar":"۞ عَسَى ٱللَّهُ أَن يَجْعَلَ بَيْنَكُمْ وَبَيْنَ ٱلَّذِينَ عَادَيْتُم مِّنْهُم مَّوَدَّةً ۚ وَٱللَّهُ قَدِيرٌ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"Perhaps Allāh will put, between you and those to whom you have been enemies among them, affection. And Allāh is competent,1 and Allāh is Forgiving and Merciful.","tr":"AAasa Allahu an yajAAalabaynakum wabayna allatheena AAadaytum minhummawaddatan wallahu qadeerun wallahughafoorun raheem","juz":28,"page":550},{"s":60,"a":8,"key":"60:8","ar":"لَّا يَنْهَىٰكُمُ ٱللَّهُ عَنِ ٱلَّذِينَ لَمْ يُقَـٰتِلُوكُمْ فِى ٱلدِّينِ وَلَمْ يُخْرِجُوكُم مِّن دِيَـٰرِكُمْ أَن تَبَرُّوهُمْ وَتُقْسِطُوٓا۟ إِلَيْهِمْ ۚ إِنَّ ٱللَّهَ يُحِبُّ ٱلْمُقْسِطِينَ","en":"Allāh does not forbid you from those who do not fight you because of religion and do not expel you from your homes - from being righteous toward them and acting justly toward them. Indeed, Allāh loves those who act justly.","tr":"La yanhakumu AllahuAAani allatheena lam yuqatilookum fee addeeniwalam yukhrijookum min diyarikum an tabarroohum watuqsitooilayhim inna Allaha yuhibbu almuqsiteen","juz":28,"page":550},{"s":60,"a":9,"key":"60:9","ar":"إِنَّمَا يَنْهَىٰكُمُ ٱللَّهُ عَنِ ٱلَّذِينَ قَـٰتَلُوكُمْ فِى ٱلدِّينِ وَأَخْرَجُوكُم مِّن دِيَـٰرِكُمْ وَظَـٰهَرُوا۟ عَلَىٰٓ إِخْرَاجِكُمْ أَن تَوَلَّوْهُمْ ۚ وَمَن يَتَوَلَّهُمْ فَأُو۟لَـٰٓئِكَ هُمُ ٱلظَّـٰلِمُونَ","en":"Allāh only forbids you from those who fight you because of religion and expel you from your homes and aid in your expulsion - [forbids] that you make allies1 of them. And whoever makes allies of them, then it is those who are the wrongdoers.","tr":"Innama yanhakumu AllahuAAani allatheena qatalookum fee addeeniwaakhrajookum min diyarikum wathaharooAAala ikhrajikum an tawallawhum waman yatawallahumfaola-ika humu aththalimoon","juz":28,"page":550},{"s":60,"a":10,"key":"60:10","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا جَآءَكُمُ ٱلْمُؤْمِنَـٰتُ مُهَـٰجِرَٰتٍ فَٱمْتَحِنُوهُنَّ ۖ ٱللَّهُ أَعْلَمُ بِإِيمَـٰنِهِنَّ ۖ فَإِنْ عَلِمْتُمُوهُنَّ مُؤْمِنَـٰتٍ فَلَا تَرْجِعُوهُنَّ إِلَى ٱلْكُفَّارِ ۖ لَا هُنَّ حِلٌّ لَّهُمْ وَلَا هُمْ يَحِلُّونَ لَهُنَّ ۖ وَءَاتُوهُم مَّآ أَنفَقُوا۟ ۚ وَلَا جُنَاحَ عَلَيْكُمْ أَن تَنكِحُوهُنَّ إِذَآ ءَاتَيْتُمُوهُنَّ أُجُورَهُنَّ ۚ وَلَا تُمْسِكُوا۟ بِعِصَمِ ٱلْكَوَافِرِ وَسْـَٔلُوا۟ مَآ أَنفَقْتُمْ وَلْيَسْـَٔلُوا۟ مَآ أَنفَقُوا۟ ۚ ذَٰلِكُمْ حُكْمُ ٱللَّهِ ۖ يَحْكُمُ بَيْنَكُمْ ۚ وَٱللَّهُ عَلِيمٌ حَكِيمٌ","en":"O you who have believed, when the believing women come to you as emigrants, examine [i.e., test] them. Allāh is most knowing as to their faith. And if you know them to be believers, then do not return them to the disbelievers; they are not lawful [wives] for them, nor are they lawful [husbands] for them. But give them [i.e., the disbelievers] what they have spent.1 And there is no blame upon you if you marry them when you have given them their due compensation [i.e., mahr]. And hold not to marriage bonds with disbelieving women, but ask for what you have spent and let them [i.e., the disbelievers] ask for what they have spent.2 That is the judgement of Allāh; He judges between you. And Allāh is Knowing and Wise.","tr":"Ya ayyuha allatheena amanooitha jaakumu almu/minatu muhajiratinfamtahinoohunna Allahu aAAlamu bi-eemanihinnafa-in AAalimtumoohunna mu/minatin falatarjiAAoohunna ila alkuffari la hunna hillunlahum wala hum yahilloona lahunna waatoohumma anfaqoo wala junaha AAalaykum an tankihoohunnaitha ataytumoohunna ojoorahunna walatumsikoo biAAisami alkawafiri was-aloo maanfaqtum walyas-aloo ma anfaqoo thalikum hukmuAllahi yahkumu baynakum wallahuAAaleemun hakeem","juz":28,"page":550},{"s":60,"a":11,"key":"60:11","ar":"وَإِن فَاتَكُمْ شَىْءٌ مِّنْ أَزْوَٰجِكُمْ إِلَى ٱلْكُفَّارِ فَعَاقَبْتُمْ فَـَٔاتُوا۟ ٱلَّذِينَ ذَهَبَتْ أَزْوَٰجُهُم مِّثْلَ مَآ أَنفَقُوا۟ ۚ وَٱتَّقُوا۟ ٱللَّهَ ٱلَّذِىٓ أَنتُم بِهِۦ مُؤْمِنُونَ","en":"And if you have lost any of your wives to the disbelievers and you subsequently obtain [something],1 then give those whose wives have gone the equivalent of what they had spent. And fear Allāh, in whom you are believers.","tr":"Wa-in fatakum shay-on min azwajikumila alkuffari faAAaqabtum faatoo allatheenathahabat azwajuhum mithla ma anfaqoo wattaqooAllaha allathee antum bihi mu/minoon","juz":28,"page":550},{"s":60,"a":12,"key":"60:12","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ إِذَا جَآءَكَ ٱلْمُؤْمِنَـٰتُ يُبَايِعْنَكَ عَلَىٰٓ أَن لَّا يُشْرِكْنَ بِٱللَّهِ شَيْـًٔا وَلَا يَسْرِقْنَ وَلَا يَزْنِينَ وَلَا يَقْتُلْنَ أَوْلَـٰدَهُنَّ وَلَا يَأْتِينَ بِبُهْتَـٰنٍ يَفْتَرِينَهُۥ بَيْنَ أَيْدِيهِنَّ وَأَرْجُلِهِنَّ وَلَا يَعْصِينَكَ فِى مَعْرُوفٍ ۙ فَبَايِعْهُنَّ وَٱسْتَغْفِرْ لَهُنَّ ٱللَّهَ ۖ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"O Prophet, when the believing women come to you pledging to you that they will not associate anything with Allāh, nor will they steal, nor will they commit unlawful sexual intercourse, nor will they kill their children, nor will they bring forth a slander they have invented between their arms and legs,1 nor will they disobey you in what is right - then accept their pledge and ask forgiveness for them of Allāh. Indeed, Allāh is Forgiving and Merciful.","tr":"Ya ayyuha annabiyyu ithajaaka almu/minatu yubayiAAnaka AAalaan la yushrikna billahi shay-an walayasriqna wala yazneena wala yaqtulna awladahunnawala ya/teena bibuhtanin yaftareenahu baynaaydeehinna waarjulihinna wala yaAAseenaka feemaAAroofin fabayiAAhunna wastaghfir lahunna Allahainna Allaha ghafoorun raheem","juz":28,"page":551},{"s":60,"a":13,"key":"60:13","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تَتَوَلَّوْا۟ قَوْمًا غَضِبَ ٱللَّهُ عَلَيْهِمْ قَدْ يَئِسُوا۟ مِنَ ٱلْـَٔاخِرَةِ كَمَا يَئِسَ ٱلْكُفَّارُ مِنْ أَصْحَـٰبِ ٱلْقُبُورِ","en":"O you who have believed, do not make allies of a people with whom Allāh has become angry. They have despaired of [reward in] the Hereafter just as the disbelievers have despaired of [meeting] the companions [i.e., inhabitants] of the graves.","tr":"Ya ayyuha allatheena amanoola tatawallaw qawman ghadiba AllahuAAalayhim qad ya-isoo mina al-akhirati kama ya-isaalkuffaru min as-habi alquboor","juz":28,"page":551},{"s":61,"a":1,"key":"61:1","ar":" سَبَّحَ لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Whatever is in the heavens and whatever is on the earth exalts Allāh,1 and He is the Exalted in Might, the Wise.","tr":"Sabbaha lillahi ma fee assamawatiwama fee al-ardi wahuwa alAAazeezu alhakeem","juz":28,"page":551},{"s":61,"a":2,"key":"61:2","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لِمَ تَقُولُونَ مَا لَا تَفْعَلُونَ","en":"O you who have believed, why do you say what you do not do?","tr":"Ya ayyuha allatheena amanoolima taqooloona ma la tafAAaloon","juz":28,"page":551},{"s":61,"a":3,"key":"61:3","ar":"كَبُرَ مَقْتًا عِندَ ٱللَّهِ أَن تَقُولُوا۟ مَا لَا تَفْعَلُونَ","en":"Greatly hateful in the sight of Allāh is that you say what you do not do.","tr":"Kabura maqtan AAinda Allahi antaqooloo ma la tafAAaloon","juz":28,"page":551},{"s":61,"a":4,"key":"61:4","ar":"إِنَّ ٱللَّهَ يُحِبُّ ٱلَّذِينَ يُقَـٰتِلُونَ فِى سَبِيلِهِۦ صَفًّا كَأَنَّهُم بُنْيَـٰنٌ مَّرْصُوصٌ","en":"Indeed, Allāh loves those who fight in His cause in a row as though they are a [single] structure joined firmly.","tr":"Inna Allaha yuhibbu allatheenayuqatiloona fee sabeelihi saffan kaannahum bunyanunmarsoos","juz":28,"page":551},{"s":61,"a":5,"key":"61:5","ar":"وَإِذْ قَالَ مُوسَىٰ لِقَوْمِهِۦ يَـٰقَوْمِ لِمَ تُؤْذُونَنِى وَقَد تَّعْلَمُونَ أَنِّى رَسُولُ ٱللَّهِ إِلَيْكُمْ ۖ فَلَمَّا زَاغُوٓا۟ أَزَاغَ ٱللَّهُ قُلُوبَهُمْ ۚ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلْفَـٰسِقِينَ","en":"And [mention, O Muḥammad], when Moses said to his people, \"O my people, why do you harm me while you certainly know that I am the messenger of Allāh to you?\" And when they deviated, Allāh caused their hearts to deviate. And Allāh does not guide the defiantly disobedient people.","tr":"Wa-ith qala moosaliqawmihi ya qawmi lima tu/thoonanee waqadtaAAlamoona annee rasoolu Allahi ilaykum falamma zaghooazagha Allahu quloobahum wallahu layahdee alqawma alfasiqeen","juz":28,"page":551},{"s":61,"a":6,"key":"61:6","ar":"وَإِذْ قَالَ عِيسَى ٱبْنُ مَرْيَمَ يَـٰبَنِىٓ إِسْرَٰٓءِيلَ إِنِّى رَسُولُ ٱللَّهِ إِلَيْكُم مُّصَدِّقًا لِّمَا بَيْنَ يَدَىَّ مِنَ ٱلتَّوْرَىٰةِ وَمُبَشِّرًۢا بِرَسُولٍ يَأْتِى مِنۢ بَعْدِى ٱسْمُهُۥٓ أَحْمَدُ ۖ فَلَمَّا جَآءَهُم بِٱلْبَيِّنَـٰتِ قَالُوا۟ هَـٰذَا سِحْرٌ مُّبِينٌ","en":"And [mention] when Jesus, the son of Mary, said, \"O Children of Israel, indeed I am the messenger of Allāh to you confirming what came before me of the Torah and bringing good tidings of a messenger to come after me, whose name is Aḥmad.\"1 But when he came to them with clear evidences, they said, \"This is obvious magic.\"2","tr":"Wa-ith qala AAeesa ibnumaryama ya banee isra-eela innee rasoolu Allahiilaykum musaddiqan lima bayna yadayya mina attawratiwamubashshiran birasoolin ya/tee min baAAdee ismuhu ahmadufalamma jaahum bilbayyinati qaloohatha sihrun mubeen","juz":28,"page":552},{"s":61,"a":7,"key":"61:7","ar":"وَمَنْ أَظْلَمُ مِمَّنِ ٱفْتَرَىٰ عَلَى ٱللَّهِ ٱلْكَذِبَ وَهُوَ يُدْعَىٰٓ إِلَى ٱلْإِسْلَـٰمِ ۚ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"And who is more unjust than one who invents about Allāh untruth while he is being invited to Islām. And Allāh does not guide the wrongdoing people.","tr":"Waman athlamu mimmani iftaraAAala Allahi alkathiba wahuwa yudAAaila al-islami wallahu layahdee alqawma aththalimeen","juz":28,"page":552},{"s":61,"a":8,"key":"61:8","ar":"يُرِيدُونَ لِيُطْفِـُٔوا۟ نُورَ ٱللَّهِ بِأَفْوَٰهِهِمْ وَٱللَّهُ مُتِمُّ نُورِهِۦ وَلَوْ كَرِهَ ٱلْكَـٰفِرُونَ","en":"They want to extinguish the light of Allāh with their mouths, but Allāh will perfect His light, although the disbelievers dislike it.","tr":"Yureedoona liyutfi-oo noora Allahibi-afwahihim wallahu mutimmu noorihi walawkariha alkafiroon","juz":28,"page":552},{"s":61,"a":9,"key":"61:9","ar":"هُوَ ٱلَّذِىٓ أَرْسَلَ رَسُولَهُۥ بِٱلْهُدَىٰ وَدِينِ ٱلْحَقِّ لِيُظْهِرَهُۥ عَلَى ٱلدِّينِ كُلِّهِۦ وَلَوْ كَرِهَ ٱلْمُشْرِكُونَ","en":"It is He who sent His Messenger with guidance and the religion of truth to manifest it over all religion, although those who associate others with Allāh dislike it.","tr":"Huwa allathee arsala rasoolahu bilhudawadeeni alhaqqi liyuthhirahu AAala addeenikullihi walaw kariha almushrikoon","juz":28,"page":552},{"s":61,"a":10,"key":"61:10","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ هَلْ أَدُلُّكُمْ عَلَىٰ تِجَـٰرَةٍ تُنجِيكُم مِّنْ عَذَابٍ أَلِيمٍ","en":"O you who have believed, shall I guide you to a transaction that will save you from a painful punishment?","tr":"Ya ayyuha allatheena amanoohal adullukum AAala tijaratin tunjeekum min AAathabinaleem","juz":28,"page":552},{"s":61,"a":11,"key":"61:11","ar":"تُؤْمِنُونَ بِٱللَّهِ وَرَسُولِهِۦ وَتُجَـٰهِدُونَ فِى سَبِيلِ ٱللَّهِ بِأَمْوَٰلِكُمْ وَأَنفُسِكُمْ ۚ ذَٰلِكُمْ خَيْرٌ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ","en":"[It is that] you believe in Allāh and His Messenger and strive in the cause of Allāh with your wealth and your lives. That is best for you, if you only knew.","tr":"Tu/minoona billahiwarasoolihi watujahidoona fee sabeeli Allahi bi-amwalikumwaanfusikum thalikum khayrun lakum in kuntum taAAlamoon","juz":28,"page":552},{"s":61,"a":12,"key":"61:12","ar":"يَغْفِرْ لَكُمْ ذُنُوبَكُمْ وَيُدْخِلْكُمْ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ وَمَسَـٰكِنَ طَيِّبَةً فِى جَنَّـٰتِ عَدْنٍ ۚ ذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"He will forgive for you your sins and admit you to gardens beneath which rivers flow and pleasant dwellings in gardens of perpetual residence. That is the great attainment.","tr":"Yaghfir lakum thunoobakumwayudkhilkum jannatin tajree min tahtihaal-anharu wamasakina tayyibatan fee jannatiAAadnin thalika alfawzu alAAatheem","juz":28,"page":552},{"s":61,"a":13,"key":"61:13","ar":"وَأُخْرَىٰ تُحِبُّونَهَا ۖ نَصْرٌ مِّنَ ٱللَّهِ وَفَتْحٌ قَرِيبٌ ۗ وَبَشِّرِ ٱلْمُؤْمِنِينَ","en":"And [you will obtain] another [favor] that you love - victory from Allāh and an imminent conquest; and give good tidings to the believers.","tr":"Waokhra tuhibboonaha nasrunmina Allahi wafathun qarreebun wabashshirialmu/mineen","juz":28,"page":552},{"s":61,"a":14,"key":"61:14","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ كُونُوٓا۟ أَنصَارَ ٱللَّهِ كَمَا قَالَ عِيسَى ٱبْنُ مَرْيَمَ لِلْحَوَارِيِّـۧنَ مَنْ أَنصَارِىٓ إِلَى ٱللَّهِ ۖ قَالَ ٱلْحَوَارِيُّونَ نَحْنُ أَنصَارُ ٱللَّهِ ۖ فَـَٔامَنَت طَّآئِفَةٌ مِّنۢ بَنِىٓ إِسْرَٰٓءِيلَ وَكَفَرَت طَّآئِفَةٌ ۖ فَأَيَّدْنَا ٱلَّذِينَ ءَامَنُوا۟ عَلَىٰ عَدُوِّهِمْ فَأَصْبَحُوا۟ ظَـٰهِرِينَ","en":"O you who have believed, be supporters of Allāh, as when Jesus, the son of Mary, said to the disciples, \"Who are my supporters for Allāh?\" The disciples said, \"We are supporters of Allāh.\" And a faction of the Children of Israel believed and a faction disbelieved. So We supported those who believed against their enemy, and they became dominant.","tr":"Ya ayyuha allatheena amanookoonoo ansara Allahi kama qala AAeesaibnu maryama lilhawariyyeena man ansaree ilaAllahi qala alhawariyyoona nahnuansaru Allahi faamanat ta-ifatun minbanee isra-eela wakafarat ta-ifatun faayyadnaallatheena amanoo AAala AAaduwwihim faasbahoothahireen","juz":28,"page":552},{"s":62,"a":1,"key":"62:1","ar":" يُسَبِّحُ لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ٱلْمَلِكِ ٱلْقُدُّوسِ ٱلْعَزِيزِ ٱلْحَكِيمِ","en":"Whatever is in the heavens and whatever is on the earth is exalting Allāh,1 the Sovereign, the Pure, the Exalted in Might, the Wise.2","tr":"Yusabbihu lillahi ma feeassamawati wama fee al-ardialmaliki alquddoosi alAAazeezi alhakeem","juz":28,"page":553},{"s":62,"a":2,"key":"62:2","ar":"هُوَ ٱلَّذِى بَعَثَ فِى ٱلْأُمِّيِّـۧنَ رَسُولًا مِّنْهُمْ يَتْلُوا۟ عَلَيْهِمْ ءَايَـٰتِهِۦ وَيُزَكِّيهِمْ وَيُعَلِّمُهُمُ ٱلْكِتَـٰبَ وَٱلْحِكْمَةَ وَإِن كَانُوا۟ مِن قَبْلُ لَفِى ضَلَـٰلٍ مُّبِينٍ","en":"It is He who has sent among the unlettered [Arabs] a Messenger from themselves reciting to them His verses and purifying them and teaching them the Book [i.e., the Qur’ān] and wisdom [i.e., the sunnah] - although they were before in clear error -","tr":"Huwa allathee baAAatha feeal-ommiyyeena rasoolan minhum yatloo AAalayhim ayatihiwayuzakkeehim wayuAAallimuhumu alkitaba walhikmatawa-in kanoo min qablu lafee dalalin mubeen","juz":28,"page":553},{"s":62,"a":3,"key":"62:3","ar":"وَءَاخَرِينَ مِنْهُمْ لَمَّا يَلْحَقُوا۟ بِهِمْ ۚ وَهُوَ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"And [to] others of them who have not yet joined them. And He is the Exalted in Might, the Wise.","tr":"Waakhareena minhum lamma yalhaqoobihim wahuwa alAAazeezu alhakeem","juz":28,"page":553},{"s":62,"a":4,"key":"62:4","ar":"ذَٰلِكَ فَضْلُ ٱللَّهِ يُؤْتِيهِ مَن يَشَآءُ ۚ وَٱللَّهُ ذُو ٱلْفَضْلِ ٱلْعَظِيمِ","en":"That is the bounty of Allāh, which He gives to whom He wills, and Allāh is the possessor of great bounty.","tr":"Thalika fadlu Allahiyu/teehi man yashao wallahu thooalfadli alAAatheem","juz":28,"page":553},{"s":62,"a":5,"key":"62:5","ar":"مَثَلُ ٱلَّذِينَ حُمِّلُوا۟ ٱلتَّوْرَىٰةَ ثُمَّ لَمْ يَحْمِلُوهَا كَمَثَلِ ٱلْحِمَارِ يَحْمِلُ أَسْفَارًۢا ۚ بِئْسَ مَثَلُ ٱلْقَوْمِ ٱلَّذِينَ كَذَّبُوا۟ بِـَٔايَـٰتِ ٱللَّهِ ۚ وَٱللَّهُ لَا يَهْدِى ٱلْقَوْمَ ٱلظَّـٰلِمِينَ","en":"The example of those who were entrusted with the Torah and then did not take it on1 is like that of a donkey who carries volumes [of books].2 Wretched is the example of the people who deny the signs of Allāh. And Allāh does not guide the wrongdoing people.","tr":"Mathalu allatheena hummiloo attawratathumma lam yahmilooha kamathali alhimariyahmilu asfaran bi/sa mathalu alqawmi allatheenakaththaboo bi-ayati Allahi wallahula yahdee alqawma aththalimeen","juz":28,"page":553},{"s":62,"a":6,"key":"62:6","ar":"قُلْ يَـٰٓأَيُّهَا ٱلَّذِينَ هَادُوٓا۟ إِن زَعَمْتُمْ أَنَّكُمْ أَوْلِيَآءُ لِلَّهِ مِن دُونِ ٱلنَّاسِ فَتَمَنَّوُا۟ ٱلْمَوْتَ إِن كُنتُمْ صَـٰدِقِينَ","en":"Say, \"O you who are Jews, if you claim that you are allies of Allāh, excluding the [other] people, then wish for death, if you should be truthful.\"","tr":"Qul ya ayyuha allatheenahadoo in zaAAamtum annakum awliyao lillahimin dooni annasi fatamannawoo almawta in kuntum sadiqeen","juz":28,"page":553},{"s":62,"a":7,"key":"62:7","ar":"وَلَا يَتَمَنَّوْنَهُۥٓ أَبَدًۢا بِمَا قَدَّمَتْ أَيْدِيهِمْ ۚ وَٱللَّهُ عَلِيمٌۢ بِٱلظَّـٰلِمِينَ","en":"But they will not wish for it, ever, because of what their hands have put forth. And Allāh is Knowing of the wrongdoers.","tr":"Wala yatamannawnahu abadan bimaqaddamat aydeehim wallahu AAaleemun biththalimeen","juz":28,"page":553},{"s":62,"a":8,"key":"62:8","ar":"قُلْ إِنَّ ٱلْمَوْتَ ٱلَّذِى تَفِرُّونَ مِنْهُ فَإِنَّهُۥ مُلَـٰقِيكُمْ ۖ ثُمَّ تُرَدُّونَ إِلَىٰ عَـٰلِمِ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ فَيُنَبِّئُكُم بِمَا كُنتُمْ تَعْمَلُونَ","en":"Say, \"Indeed, the death from which you flee - indeed, it will meet you. Then you will be returned to the Knower of the unseen and the witnessed, and He will inform you about what you used to do.\"","tr":"Qul inna almawta allathee tafirroonaminhu fa-innahu mulaqeekum thumma turaddoona ila AAalimialghaybi washshahadati fayunabbi-okum bimakuntum taAAmaloon","juz":28,"page":553},{"s":62,"a":9,"key":"62:9","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِذَا نُودِىَ لِلصَّلَوٰةِ مِن يَوْمِ ٱلْجُمُعَةِ فَٱسْعَوْا۟ إِلَىٰ ذِكْرِ ٱللَّهِ وَذَرُوا۟ ٱلْبَيْعَ ۚ ذَٰلِكُمْ خَيْرٌ لَّكُمْ إِن كُنتُمْ تَعْلَمُونَ","en":"O you who have believed, when [the adhān] is called for the prayer on the day of Jumuʿah [Friday], then proceed to the remembrance of Allāh and leave trade. That is better for you, if you only knew.","tr":"Ya ayyuha allatheena amanooitha noodiya lissalati min yawmialjumuAAati fasAAaw ila thikri Allahiwatharoo albayAAa thalikum khayrun lakum in kuntumtaAAlamoon","juz":28,"page":554},{"s":62,"a":10,"key":"62:10","ar":"فَإِذَا قُضِيَتِ ٱلصَّلَوٰةُ فَٱنتَشِرُوا۟ فِى ٱلْأَرْضِ وَٱبْتَغُوا۟ مِن فَضْلِ ٱللَّهِ وَٱذْكُرُوا۟ ٱللَّهَ كَثِيرًا لَّعَلَّكُمْ تُفْلِحُونَ","en":"And when the prayer has been concluded, disperse within the land and seek from the bounty of Allāh, and remember Allāh often that you may succeed.","tr":"Fa-itha qudiyati assalatufantashiroo fee al-ardi wabtaghoo min fadliAllahi wathkuroo Allaha katheeranlaAAallakum tuflihoon","juz":28,"page":554},{"s":62,"a":11,"key":"62:11","ar":"وَإِذَا رَأَوْا۟ تِجَـٰرَةً أَوْ لَهْوًا ٱنفَضُّوٓا۟ إِلَيْهَا وَتَرَكُوكَ قَآئِمًا ۚ قُلْ مَا عِندَ ٱللَّهِ خَيْرٌ مِّنَ ٱللَّهْوِ وَمِنَ ٱلتِّجَـٰرَةِ ۚ وَٱللَّهُ خَيْرُ ٱلرَّٰزِقِينَ","en":"But [on one occasion] when they saw a transaction or a diversion, [O Muḥammad], they rushed to it and left you standing. Say, \"What is with Allāh is better than diversion and than a transaction, and Allāh is the best of providers.\"","tr":"Wa-itha raaw tijaratan awlahwan infaddoo ilayha watarakooka qa-imanqul ma AAinda Allahi khayrun mina allahwi wamina attijaratiwallahu khayru arraziqeen","juz":28,"page":554},{"s":63,"a":1,"key":"63:1","ar":" إِذَا جَآءَكَ ٱلْمُنَـٰفِقُونَ قَالُوا۟ نَشْهَدُ إِنَّكَ لَرَسُولُ ٱللَّهِ ۗ وَٱللَّهُ يَعْلَمُ إِنَّكَ لَرَسُولُهُۥ وَٱللَّهُ يَشْهَدُ إِنَّ ٱلْمُنَـٰفِقِينَ لَكَـٰذِبُونَ","en":"When the hypocrites come to you, [O Muḥammad], they say, \"We testify that you are the Messenger of Allāh.\" And Allāh knows that you are His Messenger, and Allāh testifies that the hypocrites are liars.","tr":"Itha jaaka almunafiqoonaqaloo nashhadu innaka larasoolu Allahi wallahuyaAAlamu innaka larasooluhu wallahu yashhadu innaalmunafiqeena lakathiboon","juz":28,"page":554},{"s":63,"a":2,"key":"63:2","ar":"ٱتَّخَذُوٓا۟ أَيْمَـٰنَهُمْ جُنَّةً فَصَدُّوا۟ عَن سَبِيلِ ٱللَّهِ ۚ إِنَّهُمْ سَآءَ مَا كَانُوا۟ يَعْمَلُونَ","en":"They have taken their oaths as a cover, so they averted [people] from the way of Allāh. Indeed, it was evil that they were doing.","tr":"Ittakhathoo aymanahum junnatanfasaddoo AAan sabeeli Allahi innahum saa makanoo yaAAmaloon","juz":28,"page":554},{"s":63,"a":3,"key":"63:3","ar":"ذَٰلِكَ بِأَنَّهُمْ ءَامَنُوا۟ ثُمَّ كَفَرُوا۟ فَطُبِعَ عَلَىٰ قُلُوبِهِمْ فَهُمْ لَا يَفْقَهُونَ","en":"That is because they believed, and then they disbelieved; so their hearts were sealed over, and they do not understand.","tr":"Thalika bi-annahum amanoothumma kafaroo fatubiAAa AAala quloobihim fahum layafqahoon","juz":28,"page":554},{"s":63,"a":4,"key":"63:4","ar":"۞ وَإِذَا رَأَيْتَهُمْ تُعْجِبُكَ أَجْسَامُهُمْ ۖ وَإِن يَقُولُوا۟ تَسْمَعْ لِقَوْلِهِمْ ۖ كَأَنَّهُمْ خُشُبٌ مُّسَنَّدَةٌ ۖ يَحْسَبُونَ كُلَّ صَيْحَةٍ عَلَيْهِمْ ۚ هُمُ ٱلْعَدُوُّ فَٱحْذَرْهُمْ ۚ قَـٰتَلَهُمُ ٱللَّهُ ۖ أَنَّىٰ يُؤْفَكُونَ","en":"And when you see them, their forms please you, and if they speak, you listen to their speech. [They are] as if they were pieces of wood propped up1 - they think that every shout is against them. They are the enemy, so beware of them. May Allāh destroy them; how are they deluded?","tr":"Wa-itha raaytahum tuAAjibuka ajsamuhumwa-in yaqooloo tasmaAA liqawlihim kaannahum khushubunmusannadatun yahsaboona kulla sayhatinAAalayhim humu alAAaduwwu fahtharhum qatalahumuAllahu anna yu/fakoon","juz":28,"page":554},{"s":63,"a":5,"key":"63:5","ar":"وَإِذَا قِيلَ لَهُمْ تَعَالَوْا۟ يَسْتَغْفِرْ لَكُمْ رَسُولُ ٱللَّهِ لَوَّوْا۟ رُءُوسَهُمْ وَرَأَيْتَهُمْ يَصُدُّونَ وَهُم مُّسْتَكْبِرُونَ","en":"And when it is said to them, \"Come, the Messenger of Allāh will ask forgiveness for you,\" they turn their heads aside and you see them evading while they are arrogant.","tr":"Wa-itha qeela lahum taAAalawyastaghfir lakum rasoolu Allahi lawwaw ruoosahumwaraaytahum yasuddoona wahum mustakbiroon","juz":28,"page":555},{"s":63,"a":6,"key":"63:6","ar":"سَوَآءٌ عَلَيْهِمْ أَسْتَغْفَرْتَ لَهُمْ أَمْ لَمْ تَسْتَغْفِرْ لَهُمْ لَن يَغْفِرَ ٱللَّهُ لَهُمْ ۚ إِنَّ ٱللَّهَ لَا يَهْدِى ٱلْقَوْمَ ٱلْفَـٰسِقِينَ","en":"It is all the same for them whether you ask forgiveness for them or do not ask forgiveness for them; never will Allāh forgive them. Indeed, Allāh does not guide the defiantly disobedient people.","tr":"Sawaon AAalayhim astaghfarta lahum amlam tastaghfir lahum lan yaghfira Allahu lahum inna Allahala yahdee alqawma alfasiqeen","juz":28,"page":555},{"s":63,"a":7,"key":"63:7","ar":"هُمُ ٱلَّذِينَ يَقُولُونَ لَا تُنفِقُوا۟ عَلَىٰ مَنْ عِندَ رَسُولِ ٱللَّهِ حَتَّىٰ يَنفَضُّوا۟ ۗ وَلِلَّهِ خَزَآئِنُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَلَـٰكِنَّ ٱلْمُنَـٰفِقِينَ لَا يَفْقَهُونَ","en":"They are the ones who say, \"Do not spend on those who are with the Messenger of Allāh until they disband.\" And to Allāh belong the depositories of the heavens and the earth, but the hypocrites do not understand.","tr":"Humu allatheena yaqooloona latunfiqoo AAala man AAinda rasooli Allahi hattayanfaddoo walillahi khaza-inu assamawatiwal-ardi walakinna almunafiqeena layafqahoon","juz":28,"page":555},{"s":63,"a":8,"key":"63:8","ar":"يَقُولُونَ لَئِن رَّجَعْنَآ إِلَى ٱلْمَدِينَةِ لَيُخْرِجَنَّ ٱلْأَعَزُّ مِنْهَا ٱلْأَذَلَّ ۚ وَلِلَّهِ ٱلْعِزَّةُ وَلِرَسُولِهِۦ وَلِلْمُؤْمِنِينَ وَلَـٰكِنَّ ٱلْمُنَـٰفِقِينَ لَا يَعْلَمُونَ","en":"They say, \"If we return to al-Madīnah, the more honored [for power] will surely expel therefrom the more humble.\" And to Allāh belongs [all] honor, and to His Messenger, and to the believers, but the hypocrites do not know.","tr":"Yaqooloona la-in rajaAAna ilaalmadeenati layukhrijanna al-aAAazzu minha al-athallawalillahi alAAizzatu walirasoolihi walilmu/mineena walakinnaalmunafiqeena la yaAAlamoon","juz":28,"page":555},{"s":63,"a":9,"key":"63:9","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ لَا تُلْهِكُمْ أَمْوَٰلُكُمْ وَلَآ أَوْلَـٰدُكُمْ عَن ذِكْرِ ٱللَّهِ ۚ وَمَن يَفْعَلْ ذَٰلِكَ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْخَـٰسِرُونَ","en":"O you who have believed, let not your wealth and your children divert you from the remembrance of Allāh. And whoever does that - then those are the losers.","tr":"Ya ayyuha allatheena amanoola tulhikum amwalukum wala awladukumAAan thikri Allahi waman yafAAal thalikafaola-ika humu alkhasiroon","juz":28,"page":555},{"s":63,"a":10,"key":"63:10","ar":"وَأَنفِقُوا۟ مِن مَّا رَزَقْنَـٰكُم مِّن قَبْلِ أَن يَأْتِىَ أَحَدَكُمُ ٱلْمَوْتُ فَيَقُولَ رَبِّ لَوْلَآ أَخَّرْتَنِىٓ إِلَىٰٓ أَجَلٍ قَرِيبٍ فَأَصَّدَّقَ وَأَكُن مِّنَ ٱلصَّـٰلِحِينَ","en":"And spend [in the way of Allāh] from what We have provided you before death approaches one of you and he says, \"My Lord, if only You would delay me for a brief term so I would give charity and be of the righteous.\"","tr":"Waanfiqoo min ma razaqnakummin qabli an ya/tiya ahadakumu almawtu fayaqoola rabbilawla akhkhartanee ila ajalin qareebin faassaddaqawaakun mina assaliheen","juz":28,"page":555},{"s":63,"a":11,"key":"63:11","ar":"وَلَن يُؤَخِّرَ ٱللَّهُ نَفْسًا إِذَا جَآءَ أَجَلُهَا ۚ وَٱللَّهُ خَبِيرٌۢ بِمَا تَعْمَلُونَ","en":"But never will Allāh delay a soul when its time has come. And Allāh is Aware of what you do.","tr":"Walan yu-akhkhira Allahu nafsan ithajaa ajaluha wallahu khabeerun bimataAAmaloon","juz":28,"page":555},{"s":64,"a":1,"key":"64:1","ar":" يُسَبِّحُ لِلَّهِ مَا فِى ٱلسَّمَـٰوَٰتِ وَمَا فِى ٱلْأَرْضِ ۖ لَهُ ٱلْمُلْكُ وَلَهُ ٱلْحَمْدُ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Whatever is in the heavens and whatever is on the earth is exalting Allāh.1 To Him belongs dominion, and to Him belongs [all] praise, and He is over all things competent.","tr":"Yusabbihu lillahi ma feeassamawati wama fee al-ardilahu almulku walahu alhamdu wahuwa AAala kullishay-in qadeer","juz":28,"page":556},{"s":64,"a":2,"key":"64:2","ar":"هُوَ ٱلَّذِى خَلَقَكُمْ فَمِنكُمْ كَافِرٌ وَمِنكُم مُّؤْمِنٌ ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ بَصِيرٌ","en":"It is He who created you, and among you is the disbeliever, and among you is the believer. And Allāh, of what you do, is Seeing.","tr":"Huwa allathee khalaqakum faminkum kafirunwaminkum mu/minun wallahu bima taAAmaloonabaseer","juz":28,"page":556},{"s":64,"a":3,"key":"64:3","ar":"خَلَقَ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضَ بِٱلْحَقِّ وَصَوَّرَكُمْ فَأَحْسَنَ صُوَرَكُمْ ۖ وَإِلَيْهِ ٱلْمَصِيرُ","en":"He created the heavens and earth in truth and formed you and perfected your forms; and to Him is the [final] destination.","tr":"Khalaqa assamawati wal-ardabilhaqqi wasawwarakum faahsana suwarakumwa-ilayhi almaseer","juz":28,"page":556},{"s":64,"a":4,"key":"64:4","ar":"يَعْلَمُ مَا فِى ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَيَعْلَمُ مَا تُسِرُّونَ وَمَا تُعْلِنُونَ ۚ وَٱللَّهُ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"He knows what is within the heavens and earth and knows what you conceal and what you declare. And Allāh is Knowing of that within the breasts.","tr":"YaAAlamu ma fee assamawatiwal-ardi wayaAAlamu ma tusirroona wamatuAAlinoona wallahu AAaleemun bithati assudoor","juz":28,"page":556},{"s":64,"a":5,"key":"64:5","ar":"أَلَمْ يَأْتِكُمْ نَبَؤُا۟ ٱلَّذِينَ كَفَرُوا۟ مِن قَبْلُ فَذَاقُوا۟ وَبَالَ أَمْرِهِمْ وَلَهُمْ عَذَابٌ أَلِيمٌ","en":"Has there not come to you the news of those who disbelieved before? So they tasted the bad consequence of their affair, and they will have a painful punishment.","tr":"Alam ya/tikum nabao allatheena kafaroomin qablu fathaqoo wabala amrihim walahum AAathabunaleem","juz":28,"page":556},{"s":64,"a":6,"key":"64:6","ar":"ذَٰلِكَ بِأَنَّهُۥ كَانَت تَّأْتِيهِمْ رُسُلُهُم بِٱلْبَيِّنَـٰتِ فَقَالُوٓا۟ أَبَشَرٌ يَهْدُونَنَا فَكَفَرُوا۟ وَتَوَلَّوا۟ ۚ وَّٱسْتَغْنَى ٱللَّهُ ۚ وَٱللَّهُ غَنِىٌّ حَمِيدٌ","en":"That is because their messengers used to come to them with clear evidences, but they said, \"Shall human beings guide us?\" and disbelieved and turned away. And Allāh dispensed [with them]; and Allāh is Free of need and Praiseworthy.","tr":"Thalika bi-annahu kanatta/teehim rusuluhum bilbayyinati faqalooabasharun yahdoonana fakafaroo watawallaw wastaghnaAllahu wallahu ghaniyyun hameed","juz":28,"page":556},{"s":64,"a":7,"key":"64:7","ar":"زَعَمَ ٱلَّذِينَ كَفَرُوٓا۟ أَن لَّن يُبْعَثُوا۟ ۚ قُلْ بَلَىٰ وَرَبِّى لَتُبْعَثُنَّ ثُمَّ لَتُنَبَّؤُنَّ بِمَا عَمِلْتُمْ ۚ وَذَٰلِكَ عَلَى ٱللَّهِ يَسِيرٌ","en":"Those who disbelieve have claimed that they will never be resurrected. Say, \"Yes, by my Lord, you will surely be resurrected; then you will surely be informed of what you did. And that, for Allāh, is easy.\"","tr":"ZaAAama allatheena kafaroo an lanyubAAathoo qul bala warabbee latubAAathunna thummalatunabbaonna bima AAamiltum wathalika AAalaAllahi yaseer","juz":28,"page":556},{"s":64,"a":8,"key":"64:8","ar":"فَـَٔامِنُوا۟ بِٱللَّهِ وَرَسُولِهِۦ وَٱلنُّورِ ٱلَّذِىٓ أَنزَلْنَا ۚ وَٱللَّهُ بِمَا تَعْمَلُونَ خَبِيرٌ","en":"So believe in Allāh and His Messenger and the light [i.e., the Qur’ān] which We have sent down. And Allāh is Aware of what you do.","tr":"Faaminoo billahiwarasoolihi wannoori allathee anzalna wallahubima taAAmaloona khabeer","juz":28,"page":556},{"s":64,"a":9,"key":"64:9","ar":"يَوْمَ يَجْمَعُكُمْ لِيَوْمِ ٱلْجَمْعِ ۖ ذَٰلِكَ يَوْمُ ٱلتَّغَابُنِ ۗ وَمَن يُؤْمِنۢ بِٱللَّهِ وَيَعْمَلْ صَـٰلِحًا يُكَفِّرْ عَنْهُ سَيِّـَٔاتِهِۦ وَيُدْخِلْهُ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَدًا ۚ ذَٰلِكَ ٱلْفَوْزُ ٱلْعَظِيمُ","en":"The Day He will assemble you for the Day of Assembly - that is the Day of Deprivation.1 And whoever believes in Allāh and does righteousness - He will remove from him his misdeeds and admit him to gardens beneath which rivers flow, wherein they will abide forever. That is the great attainment.","tr":"Yawma yajmaAAukum liyawmi aljamAAi thalikayawmu attaghabuni waman yu/min billahiwayaAAmal salihan yukaffir AAanhu sayyi-atihiwayudkhilhu jannatin tajree min tahtihaal-anharu khalideena feeha abadan thalikaalfawzu alAAatheem","juz":28,"page":556},{"s":64,"a":10,"key":"64:10","ar":"وَٱلَّذِينَ كَفَرُوا۟ وَكَذَّبُوا۟ بِـَٔايَـٰتِنَآ أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلنَّارِ خَـٰلِدِينَ فِيهَا ۖ وَبِئْسَ ٱلْمَصِيرُ","en":"But the ones who disbelieved and denied Our verses - those are the companions of the Fire, abiding eternally therein; and wretched is the destination.","tr":"Wallatheena kafaroo wakaththaboobi-ayatina ola-ika as-habuannari khalideena feeha wabi/sa almaseer","juz":28,"page":557},{"s":64,"a":11,"key":"64:11","ar":"مَآ أَصَابَ مِن مُّصِيبَةٍ إِلَّا بِإِذْنِ ٱللَّهِ ۗ وَمَن يُؤْمِنۢ بِٱللَّهِ يَهْدِ قَلْبَهُۥ ۚ وَٱللَّهُ بِكُلِّ شَىْءٍ عَلِيمٌ","en":"No disaster strikes except by permission of Allāh. And whoever believes in Allāh - He will guide his heart. And Allāh is Knowing of all things.","tr":"Ma asaba min museebatinilla bi-ithni Allahi waman yu/min billahiyahdi qalbahu wallahu bikulli shay-in AAaleem","juz":28,"page":557},{"s":64,"a":12,"key":"64:12","ar":"وَأَطِيعُوا۟ ٱللَّهَ وَأَطِيعُوا۟ ٱلرَّسُولَ ۚ فَإِن تَوَلَّيْتُمْ فَإِنَّمَا عَلَىٰ رَسُولِنَا ٱلْبَلَـٰغُ ٱلْمُبِينُ","en":"And obey Allāh and obey the Messenger; but if you turn away - then upon Our Messenger is only [the duty of] clear notification.","tr":"WaateeAAoo Allaha waateeAAooarrasoola fa-in tawallaytum fa-innama AAalarasoolina albalaghu almubeen","juz":28,"page":557},{"s":64,"a":13,"key":"64:13","ar":"ٱللَّهُ لَآ إِلَـٰهَ إِلَّا هُوَ ۚ وَعَلَى ٱللَّهِ فَلْيَتَوَكَّلِ ٱلْمُؤْمِنُونَ","en":"Allāh - there is no deity except Him. And upon Allāh let the believers rely.","tr":"Allahu la ilaha illahuwa waAAala Allahi falyatawakkali almu/minoon","juz":28,"page":557},{"s":64,"a":14,"key":"64:14","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوٓا۟ إِنَّ مِنْ أَزْوَٰجِكُمْ وَأَوْلَـٰدِكُمْ عَدُوًّا لَّكُمْ فَٱحْذَرُوهُمْ ۚ وَإِن تَعْفُوا۟ وَتَصْفَحُوا۟ وَتَغْفِرُوا۟ فَإِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌ","en":"O you who have believed, indeed, among your spouses and your children are enemies to you, so beware of them. But if you pardon and overlook and forgive - then indeed, Allāh is Forgiving and Merciful.","tr":"Ya ayyuha allatheena amanooinna min azwajikum waawladikum AAaduwwan lakum fahtharoohumwa-in taAAfoo watasfahoo wataghfiroo fa-inna Allahaghafoorun raheem","juz":28,"page":557},{"s":64,"a":15,"key":"64:15","ar":"إِنَّمَآ أَمْوَٰلُكُمْ وَأَوْلَـٰدُكُمْ فِتْنَةٌ ۚ وَٱللَّهُ عِندَهُۥٓ أَجْرٌ عَظِيمٌ","en":"Your wealth and your children are but a trial, and Allāh has with Him a great reward.","tr":"Innama amwalukum waawladukumfitnatun wallahu AAindahu ajrun AAatheem","juz":28,"page":557},{"s":64,"a":16,"key":"64:16","ar":"فَٱتَّقُوا۟ ٱللَّهَ مَا ٱسْتَطَعْتُمْ وَٱسْمَعُوا۟ وَأَطِيعُوا۟ وَأَنفِقُوا۟ خَيْرًا لِّأَنفُسِكُمْ ۗ وَمَن يُوقَ شُحَّ نَفْسِهِۦ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْمُفْلِحُونَ","en":"So fear Allāh as much as you are able and listen and obey and spend [in the way of Allāh]; it is better for your selves. And whoever is protected from the stinginess of his soul - it is those who will be the successful.","tr":"Fattaqoo Allaha maistataAAtum wasmaAAoo waateeAAoo waanfiqookhayran li-anfusikum waman yooqa shuhha nafsihi faola-ikahumu almuflihoon","juz":28,"page":557},{"s":64,"a":17,"key":"64:17","ar":"إِن تُقْرِضُوا۟ ٱللَّهَ قَرْضًا حَسَنًا يُضَـٰعِفْهُ لَكُمْ وَيَغْفِرْ لَكُمْ ۚ وَٱللَّهُ شَكُورٌ حَلِيمٌ","en":"If you loan Allāh a goodly loan, He will multiply it for you and forgive you. And Allāh is [most] Appreciative1 and Forbearing,2","tr":"In tuqridoo Allaha qardanhasanan yudaAAifhu lakum wayaghfir lakum wallahushakoorun haleem","juz":28,"page":557},{"s":64,"a":18,"key":"64:18","ar":"عَـٰلِمُ ٱلْغَيْبِ وَٱلشَّهَـٰدَةِ ٱلْعَزِيزُ ٱلْحَكِيمُ","en":"Knower of the unseen and the witnessed, the Exalted in Might, the Wise.","tr":"AAalimu alghaybi washshahadatialAAazeezu alhakeem","juz":28,"page":557},{"s":65,"a":1,"key":"65:1","ar":" يَـٰٓأَيُّهَا ٱلنَّبِىُّ إِذَا طَلَّقْتُمُ ٱلنِّسَآءَ فَطَلِّقُوهُنَّ لِعِدَّتِهِنَّ وَأَحْصُوا۟ ٱلْعِدَّةَ ۖ وَٱتَّقُوا۟ ٱللَّهَ رَبَّكُمْ ۖ لَا تُخْرِجُوهُنَّ مِنۢ بُيُوتِهِنَّ وَلَا يَخْرُجْنَ إِلَّآ أَن يَأْتِينَ بِفَـٰحِشَةٍ مُّبَيِّنَةٍ ۚ وَتِلْكَ حُدُودُ ٱللَّهِ ۚ وَمَن يَتَعَدَّ حُدُودَ ٱللَّهِ فَقَدْ ظَلَمَ نَفْسَهُۥ ۚ لَا تَدْرِى لَعَلَّ ٱللَّهَ يُحْدِثُ بَعْدَ ذَٰلِكَ أَمْرًا","en":"O Prophet, when you [Muslims] divorce women, divorce them for [the commencement of] their waiting period and keep count of the waiting period,1 and fear Allāh, your Lord. Do not turn them out of their [husbands'] houses, nor should they [themselves] leave [during that period] unless they are committing a clear immorality. And those are the limits [set by] Allāh. And whoever transgresses the limits of Allāh has certainly wronged himself. You know not; perhaps Allāh will bring about after that a [different] matter.2","tr":"Ya ayyuha annabiyyu ithatallaqtumu annisaa fatalliqoohunnaliAAiddatihinna waahsoo alAAiddata wattaqoo Allaharabbakum la tukhrijoohunna min buyootihinna walayakhrujna illa an ya/teena bifahishatinmubayyinatin watilka hudoodu Allahi wamanyataAAadda hudooda Allahi faqad thalamanafsahu la tadree laAAalla Allaha yuhdithubaAAda thalika amra","juz":28,"page":558},{"s":65,"a":2,"key":"65:2","ar":"فَإِذَا بَلَغْنَ أَجَلَهُنَّ فَأَمْسِكُوهُنَّ بِمَعْرُوفٍ أَوْ فَارِقُوهُنَّ بِمَعْرُوفٍ وَأَشْهِدُوا۟ ذَوَىْ عَدْلٍ مِّنكُمْ وَأَقِيمُوا۟ ٱلشَّهَـٰدَةَ لِلَّهِ ۚ ذَٰلِكُمْ يُوعَظُ بِهِۦ مَن كَانَ يُؤْمِنُ بِٱللَّهِ وَٱلْيَوْمِ ٱلْـَٔاخِرِ ۚ وَمَن يَتَّقِ ٱللَّهَ يَجْعَل لَّهُۥ مَخْرَجًا","en":"And when they have [nearly] fulfilled their term, either retain them according to acceptable terms or part with them according to acceptable terms. And bring to witness two just men from among you and establish the testimony for [the acceptance of] Allāh. That is instructed to whoever should believe in Allāh and the Last Day. And whoever fears Allāh - He will make for him a way out1","tr":"Fa-itha balaghna ajalahunnafaamsikoohunna bimaAAroofin aw fariqoohunna bimaAAroofinwaashhidoo thaway AAadlin minkum waaqeemoo ashshahadatalillahi thalikum yooAAathu bihi man kanayu/minu billahi walyawmi al-akhiriwaman yattaqi Allaha yajAAal lahu makhraja","juz":28,"page":558},{"s":65,"a":3,"key":"65:3","ar":"وَيَرْزُقْهُ مِنْ حَيْثُ لَا يَحْتَسِبُ ۚ وَمَن يَتَوَكَّلْ عَلَى ٱللَّهِ فَهُوَ حَسْبُهُۥٓ ۚ إِنَّ ٱللَّهَ بَـٰلِغُ أَمْرِهِۦ ۚ قَدْ جَعَلَ ٱللَّهُ لِكُلِّ شَىْءٍ قَدْرًا","en":"And will provide for him from where he does not expect. And whoever relies upon Allāh - then He is sufficient for him. Indeed, Allāh will accomplish His purpose. Allāh has already set for everything a [decreed] extent.","tr":"Wayarzuqhu min haythu la yahtasibuwaman yatawakkal AAala Allahi fahuwa hasbuhuinna Allaha balighu amrihi qad jaAAala Allahulikulli shay-in qadra","juz":28,"page":558},{"s":65,"a":4,"key":"65:4","ar":"وَٱلَّـٰٓـِٔى يَئِسْنَ مِنَ ٱلْمَحِيضِ مِن نِّسَآئِكُمْ إِنِ ٱرْتَبْتُمْ فَعِدَّتُهُنَّ ثَلَـٰثَةُ أَشْهُرٍ وَٱلَّـٰٓـِٔى لَمْ يَحِضْنَ ۚ وَأُو۟لَـٰتُ ٱلْأَحْمَالِ أَجَلُهُنَّ أَن يَضَعْنَ حَمْلَهُنَّ ۚ وَمَن يَتَّقِ ٱللَّهَ يَجْعَل لَّهُۥ مِنْ أَمْرِهِۦ يُسْرًا","en":"And those who no longer expect menstruation among your women - if you doubt, then their period is three months, and [also for] those who have not menstruated. And for those who are pregnant, their term is until they give birth.1 And whoever fears Allāh - He will make for him of his matter ease.","tr":"Walla-ee ya-isna mina almaheedimin nisa-ikum ini irtabtum faAAiddatuhunna thalathatuashhurin walla-ee lam yahidna waolatual-ahmali ajaluhunna an yadaAAna hamlahunnawaman yattaqi Allaha yajAAal lahu min amrihi yusra","juz":28,"page":558},{"s":65,"a":5,"key":"65:5","ar":"ذَٰلِكَ أَمْرُ ٱللَّهِ أَنزَلَهُۥٓ إِلَيْكُمْ ۚ وَمَن يَتَّقِ ٱللَّهَ يُكَفِّرْ عَنْهُ سَيِّـَٔاتِهِۦ وَيُعْظِمْ لَهُۥٓ أَجْرًا","en":"That is the command of Allāh, which He has sent down to you; and whoever fears Allāh - He will remove for him his misdeeds and make great for him his reward.","tr":"Thalika amru Allahi anzalahuilaykum waman yattaqi Allaha yukaffir AAanhu sayyi-atihiwayuAAthim lahu ajra","juz":28,"page":558},{"s":65,"a":6,"key":"65:6","ar":"أَسْكِنُوهُنَّ مِنْ حَيْثُ سَكَنتُم مِّن وُجْدِكُمْ وَلَا تُضَآرُّوهُنَّ لِتُضَيِّقُوا۟ عَلَيْهِنَّ ۚ وَإِن كُنَّ أُو۟لَـٰتِ حَمْلٍ فَأَنفِقُوا۟ عَلَيْهِنَّ حَتَّىٰ يَضَعْنَ حَمْلَهُنَّ ۚ فَإِنْ أَرْضَعْنَ لَكُمْ فَـَٔاتُوهُنَّ أُجُورَهُنَّ ۖ وَأْتَمِرُوا۟ بَيْنَكُم بِمَعْرُوفٍ ۖ وَإِن تَعَاسَرْتُمْ فَسَتُرْضِعُ لَهُۥٓ أُخْرَىٰ","en":"Lodge them1 [in a section] of where you dwell out of your means and do not harm them in order to oppress them.2 And if they should be pregnant, then spend on them until they give birth. And if they breastfeed for you, then give them their payment and confer among yourselves in the acceptable way; but if you are in discord, then there may breastfeed for him [i.e., the father] another woman.3","tr":"Askinoohunna min haythu sakantum minwujdikum wala tudarroohunna litudayyiqooAAalayhinna wa-in kunna olati hamlin faanfiqooAAalayhinna hatta yadaAAna hamlahunnafa-in ardaAAna lakum faatoohunna ojoorahunnawa/tamiroo baynakum bimaAAroofin wa-in taAAasartum fasaturdiAAulahu okhra","juz":28,"page":559},{"s":65,"a":7,"key":"65:7","ar":"لِيُنفِقْ ذُو سَعَةٍ مِّن سَعَتِهِۦ ۖ وَمَن قُدِرَ عَلَيْهِ رِزْقُهُۥ فَلْيُنفِقْ مِمَّآ ءَاتَىٰهُ ٱللَّهُ ۚ لَا يُكَلِّفُ ٱللَّهُ نَفْسًا إِلَّا مَآ ءَاتَىٰهَا ۚ سَيَجْعَلُ ٱللَّهُ بَعْدَ عُسْرٍ يُسْرًا","en":"Let a man of wealth spend from his wealth, and he whose provision is restricted - let him spend from what Allāh has given him. Allāh does not charge a soul except [according to] what He has given it. Allāh will bring about, after hardship, ease [i.e., relief].","tr":"Liyunfiq thoo saAAatin min saAAatihiwaman qudira AAalayhi rizquhu falyunfiq mimma atahuAllahu la yukallifu Allahu nafsan illama ataha sayajAAalu AllahubaAAda AAusrin yusra","juz":28,"page":559},{"s":65,"a":8,"key":"65:8","ar":"وَكَأَيِّن مِّن قَرْيَةٍ عَتَتْ عَنْ أَمْرِ رَبِّهَا وَرُسُلِهِۦ فَحَاسَبْنَـٰهَا حِسَابًا شَدِيدًا وَعَذَّبْنَـٰهَا عَذَابًا نُّكْرًا","en":"And how many a city was insolent toward the command of its Lord and His messengers, so We took it to severe account and punished it with a terrible punishment.","tr":"Wakaayyin min qaryatin AAatat AAan amrirabbiha warusulihi fahasabnaha hisabanshadeedan waAAaththabnaha AAathabannukra","juz":28,"page":559},{"s":65,"a":9,"key":"65:9","ar":"فَذَاقَتْ وَبَالَ أَمْرِهَا وَكَانَ عَـٰقِبَةُ أَمْرِهَا خُسْرًا","en":"And it tasted the bad consequence of its affair [i.e., rebellion], and the outcome of its affair was loss.","tr":"Fathaqat wabala amrihawakana AAaqibatu amriha khusra","juz":28,"page":559},{"s":65,"a":10,"key":"65:10","ar":"أَعَدَّ ٱللَّهُ لَهُمْ عَذَابًا شَدِيدًا ۖ فَٱتَّقُوا۟ ٱللَّهَ يَـٰٓأُو۟لِى ٱلْأَلْبَـٰبِ ٱلَّذِينَ ءَامَنُوا۟ ۚ قَدْ أَنزَلَ ٱللَّهُ إِلَيْكُمْ ذِكْرًا","en":"Allāh has prepared for them a severe punishment; so fear Allāh, O you of understanding who have believed. Allāh has sent down to you a message [i.e., the Qur’ān].1","tr":"aAAadda Allahu lahum AAathabanshadeedan fattaqoo Allaha ya olee al-albabiallatheena amanoo qad anzala Allahu ilaykum thikra","juz":28,"page":559},{"s":65,"a":11,"key":"65:11","ar":"رَّسُولًا يَتْلُوا۟ عَلَيْكُمْ ءَايَـٰتِ ٱللَّهِ مُبَيِّنَـٰتٍ لِّيُخْرِجَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ مِنَ ٱلظُّلُمَـٰتِ إِلَى ٱلنُّورِ ۚ وَمَن يُؤْمِنۢ بِٱللَّهِ وَيَعْمَلْ صَـٰلِحًا يُدْخِلْهُ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَدًا ۖ قَدْ أَحْسَنَ ٱللَّهُ لَهُۥ رِزْقًا","en":"[He sent] a Messenger [i.e., Muḥammad (ﷺ)] reciting to you the distinct verses of Allāh that He may bring out those who believe and do righteous deeds from darknesses into the light. And whoever believes in Allāh and does righteousness - He will admit him into gardens beneath which rivers flow to abide therein forever. Allāh will have perfected for him a provision.","tr":"Rasoolan yatloo AAalaykum ayatiAllahi mubayyinatin liyukhrija allatheena amanoowaAAamiloo assalihati mina aththulumatiila annoori waman yu/min billahiwayaAAmal salihan yudkhilhu jannatin tajreemin tahtiha al-anharu khalideena feehaabadan qad ahsana Allahu lahu rizqa","juz":28,"page":559},{"s":65,"a":12,"key":"65:12","ar":"ٱللَّهُ ٱلَّذِى خَلَقَ سَبْعَ سَمَـٰوَٰتٍ وَمِنَ ٱلْأَرْضِ مِثْلَهُنَّ يَتَنَزَّلُ ٱلْأَمْرُ بَيْنَهُنَّ لِتَعْلَمُوٓا۟ أَنَّ ٱللَّهَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ وَأَنَّ ٱللَّهَ قَدْ أَحَاطَ بِكُلِّ شَىْءٍ عِلْمًۢا","en":"It is Allāh who has created seven heavens and of the earth, the like of them.1 [His] command descends among them so you may know that Allāh is over all things competent and that Allāh has encompassed all things in knowledge.","tr":"Allahu allathee khalaqa sabAAasamawatin wamina al-ardi mithlahunnayatanazzalu al-amru baynahunna litaAAlamoo anna AllahaAAala kulli shay-in qadeerun waanna Allaha qad ahatabikulli shay-in AAilma","juz":28,"page":559},{"s":66,"a":1,"key":"66:1","ar":" يَـٰٓأَيُّهَا ٱلنَّبِىُّ لِمَ تُحَرِّمُ مَآ أَحَلَّ ٱللَّهُ لَكَ ۖ تَبْتَغِى مَرْضَاتَ أَزْوَٰجِكَ ۚ وَٱللَّهُ غَفُورٌ رَّحِيمٌ","en":"O Prophet, why do you prohibit [yourself from] what Allāh has made lawful for you, seeking the approval of your wives? And Allāh is Forgiving and Merciful.","tr":"Ya ayyuha annabiyyulima tuharrimu ma ahalla Allahu lakatabtaghee mardata azwajika wallahughafoorun raheem","juz":28,"page":560},{"s":66,"a":2,"key":"66:2","ar":"قَدْ فَرَضَ ٱللَّهُ لَكُمْ تَحِلَّةَ أَيْمَـٰنِكُمْ ۚ وَٱللَّهُ مَوْلَىٰكُمْ ۖ وَهُوَ ٱلْعَلِيمُ ٱلْحَكِيمُ","en":"Allāh has already ordained for you [Muslims] the dissolution of your oaths.1 And Allāh is your protector, and He is the Knowing, the Wise.","tr":"Qad farada Allahu lakum tahillataaymanikum wallahu mawlakum wahuwaalAAaleemu alhakeem","juz":28,"page":560},{"s":66,"a":3,"key":"66:3","ar":"وَإِذْ أَسَرَّ ٱلنَّبِىُّ إِلَىٰ بَعْضِ أَزْوَٰجِهِۦ حَدِيثًا فَلَمَّا نَبَّأَتْ بِهِۦ وَأَظْهَرَهُ ٱللَّهُ عَلَيْهِ عَرَّفَ بَعْضَهُۥ وَأَعْرَضَ عَنۢ بَعْضٍ ۖ فَلَمَّا نَبَّأَهَا بِهِۦ قَالَتْ مَنْ أَنۢبَأَكَ هَـٰذَا ۖ قَالَ نَبَّأَنِىَ ٱلْعَلِيمُ ٱلْخَبِيرُ","en":"And [remember] when the Prophet confided to one of his wives a statement; and when she informed [another] of it and Allāh showed it to him, he made known part of it and ignored a part. And when he informed her about it, she said, \"Who told you this?\" He said, \"I was informed by the Knowing, the Aware.\"","tr":"Wa-ith asarra annabiyyu ilabaAAdi azwajihi hadeethan falammanabbaat bihi waathharahu Allahu AAalayhiAAarrafa baAAdahu waaAArada AAan baAAdinfalamma nabbaaha bihi qalat man anbaaka hathaqala nabbaaniya alAAaleemu alkhabeer","juz":28,"page":560},{"s":66,"a":4,"key":"66:4","ar":"إِن تَتُوبَآ إِلَى ٱللَّهِ فَقَدْ صَغَتْ قُلُوبُكُمَا ۖ وَإِن تَظَـٰهَرَا عَلَيْهِ فَإِنَّ ٱللَّهَ هُوَ مَوْلَىٰهُ وَجِبْرِيلُ وَصَـٰلِحُ ٱلْمُؤْمِنِينَ ۖ وَٱلْمَلَـٰٓئِكَةُ بَعْدَ ذَٰلِكَ ظَهِيرٌ","en":"If you two [wives] repent to Allāh, [it is best], for your hearts have deviated. But if you cooperate against him - then indeed Allāh is his protector, and Gabriel and the righteous of the believers and the angels, moreover, are [his] assistants.","tr":"In tatooba ila Allahifaqad saghat quloobukuma wa-in tathaharaAAalayhi fa-inna Allaha huwa mawlahu wajibreelu wasalihualmu/mineena walmala-ikatu baAAda thalika thaheer","juz":28,"page":560},{"s":66,"a":5,"key":"66:5","ar":"عَسَىٰ رَبُّهُۥٓ إِن طَلَّقَكُنَّ أَن يُبْدِلَهُۥٓ أَزْوَٰجًا خَيْرًا مِّنكُنَّ مُسْلِمَـٰتٍ مُّؤْمِنَـٰتٍ قَـٰنِتَـٰتٍ تَـٰٓئِبَـٰتٍ عَـٰبِدَٰتٍ سَـٰٓئِحَـٰتٍ ثَيِّبَـٰتٍ وَأَبْكَارًا","en":"Perhaps his Lord, if he divorced you [all], would substitute for him wives better than you - submitting [to Allāh], believing, devoutly obedient, repentant, worshipping, and traveling1 - [ones] previously married and virgins.","tr":"AAasa rabbuhu in tallaqakunnaan yubdilahu azwajan khayran minkunna muslimatinmu/minatin qanitatin ta-ibatinAAabidatin sa-ihatin thayyibatinwaabkara","juz":28,"page":560},{"s":66,"a":6,"key":"66:6","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ قُوٓا۟ أَنفُسَكُمْ وَأَهْلِيكُمْ نَارًا وَقُودُهَا ٱلنَّاسُ وَٱلْحِجَارَةُ عَلَيْهَا مَلَـٰٓئِكَةٌ غِلَاظٌ شِدَادٌ لَّا يَعْصُونَ ٱللَّهَ مَآ أَمَرَهُمْ وَيَفْعَلُونَ مَا يُؤْمَرُونَ","en":"O you who have believed, protect yourselves and your families from a Fire whose fuel is people and stones, over which are [appointed] angels, harsh and severe; they do not disobey Allāh in what He commands them but do what they are commanded.","tr":"Ya ayyuha allatheena amanooqoo anfusakum waahleekum naran waqooduha annasuwalhijaratu AAalayha mala-ikatunghilathun shidadun la yaAAsoonaAllaha ma amarahum wayafAAaloona mayu/maroon","juz":28,"page":560},{"s":66,"a":7,"key":"66:7","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ كَفَرُوا۟ لَا تَعْتَذِرُوا۟ ٱلْيَوْمَ ۖ إِنَّمَا تُجْزَوْنَ مَا كُنتُمْ تَعْمَلُونَ","en":"O you who have disbelieved, make no excuses that Day. You will only be recompensed for what you used to do.","tr":"Ya ayyuha allatheenakafaroo la taAAtathiroo alyawma innamatujzawna ma kuntum taAAmaloon","juz":28,"page":560},{"s":66,"a":8,"key":"66:8","ar":"يَـٰٓأَيُّهَا ٱلَّذِينَ ءَامَنُوا۟ تُوبُوٓا۟ إِلَى ٱللَّهِ تَوْبَةً نَّصُوحًا عَسَىٰ رَبُّكُمْ أَن يُكَفِّرَ عَنكُمْ سَيِّـَٔاتِكُمْ وَيُدْخِلَكُمْ جَنَّـٰتٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ يَوْمَ لَا يُخْزِى ٱللَّهُ ٱلنَّبِىَّ وَٱلَّذِينَ ءَامَنُوا۟ مَعَهُۥ ۖ نُورُهُمْ يَسْعَىٰ بَيْنَ أَيْدِيهِمْ وَبِأَيْمَـٰنِهِمْ يَقُولُونَ رَبَّنَآ أَتْمِمْ لَنَا نُورَنَا وَٱغْفِرْ لَنَآ ۖ إِنَّكَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"O you who have believed, repent to Allāh with sincere repentance. Perhaps1 your Lord will remove from you your misdeeds and admit you into gardens beneath which rivers flow [on] the Day when Allāh will not disgrace the Prophet and those who believed with him. Their light will proceed before them and on their right; they will say, \"Our Lord, perfect for us our light and forgive us. Indeed, You are over all things competent.\"","tr":"Ya ayyuha allatheena amanootooboo ila Allahi tawbatan nasoohanAAasa rabbukum an yukaffira AAankum sayyi-atikumwayudkhilakum jannatin tajree min tahtihaal-anharu yawma la yukhzee Allahu annabiyyawallatheena amanoo maAAahu nooruhum yasAAabayna aydeehim wabi-aymanihim yaqooloona rabbanaatmim lana noorana waghfir lanainnaka AAala kulli shay-in qadeer","juz":28,"page":561},{"s":66,"a":9,"key":"66:9","ar":"يَـٰٓأَيُّهَا ٱلنَّبِىُّ جَـٰهِدِ ٱلْكُفَّارَ وَٱلْمُنَـٰفِقِينَ وَٱغْلُظْ عَلَيْهِمْ ۚ وَمَأْوَىٰهُمْ جَهَنَّمُ ۖ وَبِئْسَ ٱلْمَصِيرُ","en":"O Prophet, strive against the disbelievers and the hypocrites and be harsh upon them. And their refuge is Hell, and wretched is the destination.","tr":"Ya ayyuha annabiyyu jahidialkuffara walmunafiqeena waghluthAAalayhim wama/wahum jahannamu wabi/sa almaseer","juz":28,"page":561},{"s":66,"a":10,"key":"66:10","ar":"ضَرَبَ ٱللَّهُ مَثَلًا لِّلَّذِينَ كَفَرُوا۟ ٱمْرَأَتَ نُوحٍ وَٱمْرَأَتَ لُوطٍ ۖ كَانَتَا تَحْتَ عَبْدَيْنِ مِنْ عِبَادِنَا صَـٰلِحَيْنِ فَخَانَتَاهُمَا فَلَمْ يُغْنِيَا عَنْهُمَا مِنَ ٱللَّهِ شَيْـًٔا وَقِيلَ ٱدْخُلَا ٱلنَّارَ مَعَ ٱلدَّٰخِلِينَ","en":"Allāh presents an example of those who disbelieved: the wife of Noah and the wife of Lot. They were under two of Our righteous servants but betrayed them,1 so they [i.e., those prophets] did not avail them from Allāh at all, and it was said, \"Enter the Fire with those who enter.\"","tr":"Daraba Allahu mathalan lillatheenakafaroo imraata noohin wamraata lootin kanatatahta AAabdayni min AAibadina salihaynifakhanatahuma falam yughniya AAanhumamina Allahi shay-an waqeela odkhula annaramaAAa addakhileen","juz":28,"page":561},{"s":66,"a":11,"key":"66:11","ar":"وَضَرَبَ ٱللَّهُ مَثَلًا لِّلَّذِينَ ءَامَنُوا۟ ٱمْرَأَتَ فِرْعَوْنَ إِذْ قَالَتْ رَبِّ ٱبْنِ لِى عِندَكَ بَيْتًا فِى ٱلْجَنَّةِ وَنَجِّنِى مِن فِرْعَوْنَ وَعَمَلِهِۦ وَنَجِّنِى مِنَ ٱلْقَوْمِ ٱلظَّـٰلِمِينَ","en":"And Allāh presents an example of those who believed: the wife of Pharaoh, when she said, \"My Lord, build for me near You a house in Paradise and save me from Pharaoh and his deeds and save me from the wrongdoing people.\"","tr":"Wadaraba Allahu mathalan lillatheenaamanoo imraata firAAawna ith qalat rabbiibni lee AAindaka baytan fee aljannati wanajjinee min firAAawnawaAAamalihi wanajjinee mina alqawmi aththalimeen","juz":28,"page":561},{"s":66,"a":12,"key":"66:12","ar":"وَمَرْيَمَ ٱبْنَتَ عِمْرَٰنَ ٱلَّتِىٓ أَحْصَنَتْ فَرْجَهَا فَنَفَخْنَا فِيهِ مِن رُّوحِنَا وَصَدَّقَتْ بِكَلِمَـٰتِ رَبِّهَا وَكُتُبِهِۦ وَكَانَتْ مِنَ ٱلْقَـٰنِتِينَ","en":"And [the example of] Mary, the daughter of ʿImrān, who guarded her chastity, so We blew into [her garment] through Our angel [i.e., Gabriel], and she believed in the words of her Lord and His scriptures and was of the devoutly obedient.","tr":"Wamaryama ibnata AAimrana allatee ahsanatfarjaha fanafakhna feehi min roohinawasaddaqat bikalimati rabbiha wakutubihi wakanatmina alqaniteen","juz":28,"page":561},{"s":67,"a":1,"key":"67:1","ar":" تَبَـٰرَكَ ٱلَّذِى بِيَدِهِ ٱلْمُلْكُ وَهُوَ عَلَىٰ كُلِّ شَىْءٍ قَدِيرٌ","en":"Blessed is He in whose hand is dominion, and He is over all things competent -","tr":"Tabaraka allathee biyadihialmulku wahuwa AAala kulli shay-in qadeer","juz":29,"page":562},{"s":67,"a":2,"key":"67:2","ar":"ٱلَّذِى خَلَقَ ٱلْمَوْتَ وَٱلْحَيَوٰةَ لِيَبْلُوَكُمْ أَيُّكُمْ أَحْسَنُ عَمَلًا ۚ وَهُوَ ٱلْعَزِيزُ ٱلْغَفُورُ","en":"[He] who created death and life to test you [as to] which of you is best in deed - and He is the Exalted in Might, the Forgiving -","tr":"Allathee khalaqa almawta walhayataliyabluwakum ayyukum ahsanu AAamalan wahuwa alAAazeezualghafoor","juz":29,"page":562},{"s":67,"a":3,"key":"67:3","ar":"ٱلَّذِى خَلَقَ سَبْعَ سَمَـٰوَٰتٍ طِبَاقًا ۖ مَّا تَرَىٰ فِى خَلْقِ ٱلرَّحْمَـٰنِ مِن تَفَـٰوُتٍ ۖ فَٱرْجِعِ ٱلْبَصَرَ هَلْ تَرَىٰ مِن فُطُورٍ","en":"[And] who created seven heavens in layers.1 You do not see in the creation of the Most Merciful any inconsistency. So return [your] vision [to the sky]; do you see any breaks?","tr":"Allathee khalaqa sabAAa samawatintibaqan ma tara fee khalqi arrahmanimin tafawutin farjiAAi albasara hal taramin futoor","juz":29,"page":562},{"s":67,"a":4,"key":"67:4","ar":"ثُمَّ ٱرْجِعِ ٱلْبَصَرَ كَرَّتَيْنِ يَنقَلِبْ إِلَيْكَ ٱلْبَصَرُ خَاسِئًا وَهُوَ حَسِيرٌ","en":"Then return [your] vision twice again.1 [Your] vision will return to you humbled while it is fatigued.","tr":"Thumma irjiAAi albasara karratayniyanqalib ilayka albasaru khasi-an wahuwa haseer","juz":29,"page":562},{"s":67,"a":5,"key":"67:5","ar":"وَلَقَدْ زَيَّنَّا ٱلسَّمَآءَ ٱلدُّنْيَا بِمَصَـٰبِيحَ وَجَعَلْنَـٰهَا رُجُومًا لِّلشَّيَـٰطِينِ ۖ وَأَعْتَدْنَا لَهُمْ عَذَابَ ٱلسَّعِيرِ","en":"And We have certainly beautified the nearest heaven with lamps [i.e., stars] and have made [from] them what is thrown at the devils1 and have prepared for them the punishment of the Blaze.","tr":"Walaqad zayyanna assamaaaddunya bimasabeeha wajaAAalnaharujooman lishshayateeni waaAAtadna lahumAAathaba assaAAeer","juz":29,"page":562},{"s":67,"a":6,"key":"67:6","ar":"وَلِلَّذِينَ كَفَرُوا۟ بِرَبِّهِمْ عَذَابُ جَهَنَّمَ ۖ وَبِئْسَ ٱلْمَصِيرُ","en":"And for those who disbelieved in their Lord is the punishment of Hell, and wretched is the destination.","tr":"Walillatheena kafaroo birabbihim AAathabujahannama wabi/sa almaseer","juz":29,"page":562},{"s":67,"a":7,"key":"67:7","ar":"إِذَآ أُلْقُوا۟ فِيهَا سَمِعُوا۟ لَهَا شَهِيقًا وَهِىَ تَفُورُ","en":"When they are thrown into it, they hear from it a [dreadful] inhaling while it boils up.","tr":"Itha olqoo feeha samiAAoo lahashaheeqan wahiya tafoor","juz":29,"page":562},{"s":67,"a":8,"key":"67:8","ar":"تَكَادُ تَمَيَّزُ مِنَ ٱلْغَيْظِ ۖ كُلَّمَآ أُلْقِىَ فِيهَا فَوْجٌ سَأَلَهُمْ خَزَنَتُهَآ أَلَمْ يَأْتِكُمْ نَذِيرٌ","en":"It almost bursts with rage. Every time a company is thrown into it, its keepers ask them, \"Did there not come to you a warner?\"","tr":"Takadu tamayyazu mina alghaythikullama olqiya feeha fawjun saalahum khazanatuhaalam ya/tikum natheer","juz":29,"page":562},{"s":67,"a":9,"key":"67:9","ar":"قَالُوا۟ بَلَىٰ قَدْ جَآءَنَا نَذِيرٌ فَكَذَّبْنَا وَقُلْنَا مَا نَزَّلَ ٱللَّهُ مِن شَىْءٍ إِنْ أَنتُمْ إِلَّا فِى ضَلَـٰلٍ كَبِيرٍ","en":"They will say, \"Yes, a warner had come to us, but we denied and said, 'Allāh has not sent down anything. You are not but in great error.'\"","tr":"Qaloo bala qad jaananatheerun fakaththabna waqulna manazzala Allahu min shay-in in antum illa fee dalalinkabeer","juz":29,"page":562},{"s":67,"a":10,"key":"67:10","ar":"وَقَالُوا۟ لَوْ كُنَّا نَسْمَعُ أَوْ نَعْقِلُ مَا كُنَّا فِىٓ أَصْحَـٰبِ ٱلسَّعِيرِ","en":"And they will say, \"If only we had been listening or reasoning, we would not be among the companions of the Blaze.\"","tr":"Waqaloo law kunna nasmaAAu awnaAAqilu ma kunna fee as-habi assaAAeer","juz":29,"page":562},{"s":67,"a":11,"key":"67:11","ar":"فَٱعْتَرَفُوا۟ بِذَنۢبِهِمْ فَسُحْقًا لِّأَصْحَـٰبِ ٱلسَّعِيرِ","en":"And they will admit their sin, so [it is] alienation1 for the companions of the Blaze.","tr":"FaAAtarafoo bithanbihim fasuhqanli-as-habi assaAAeer","juz":29,"page":562},{"s":67,"a":12,"key":"67:12","ar":"إِنَّ ٱلَّذِينَ يَخْشَوْنَ رَبَّهُم بِٱلْغَيْبِ لَهُم مَّغْفِرَةٌ وَأَجْرٌ كَبِيرٌ","en":"Indeed, those who fear their Lord unseen will have forgiveness and great reward.","tr":"Inna allatheena yakhshawna rabbahumbilghaybi lahum maghfiratun waajrun kabeer","juz":29,"page":562},{"s":67,"a":13,"key":"67:13","ar":"وَأَسِرُّوا۟ قَوْلَكُمْ أَوِ ٱجْهَرُوا۟ بِهِۦٓ ۖ إِنَّهُۥ عَلِيمٌۢ بِذَاتِ ٱلصُّدُورِ","en":"And conceal your speech or publicize it; indeed, He is Knowing of that within the breasts.","tr":"Waasirroo qawlakum awi ijharoo bihi innahuAAaleemun bithati assudoor","juz":29,"page":563},{"s":67,"a":14,"key":"67:14","ar":"أَلَا يَعْلَمُ مَنْ خَلَقَ وَهُوَ ٱللَّطِيفُ ٱلْخَبِيرُ","en":"Does He who created not know,1 while He is the Subtle, the Aware?","tr":"Ala yaAAlamu man khalaqa wahuwa allateefualkhabeer","juz":29,"page":563},{"s":67,"a":15,"key":"67:15","ar":"هُوَ ٱلَّذِى جَعَلَ لَكُمُ ٱلْأَرْضَ ذَلُولًا فَٱمْشُوا۟ فِى مَنَاكِبِهَا وَكُلُوا۟ مِن رِّزْقِهِۦ ۖ وَإِلَيْهِ ٱلنُّشُورُ","en":"It is He who made the earth tame1 for you - so walk among its slopes and eat of His provision - and to Him is the resurrection.","tr":"Huwa allathee jaAAala lakumu al-ardathaloolan famshoo fee manakibihawakuloo min rizqihi wa-ilayhi annushoor","juz":29,"page":563},{"s":67,"a":16,"key":"67:16","ar":"ءَأَمِنتُم مَّن فِى ٱلسَّمَآءِ أَن يَخْسِفَ بِكُمُ ٱلْأَرْضَ فَإِذَا هِىَ تَمُورُ","en":"Do you feel secure that He who is above1 would not cause the earth to swallow you and suddenly it would sway?2","tr":"Aamintum man fee assama-i anyakhsifa bikumu al-arda fa-itha hiya tamoor","juz":29,"page":563},{"s":67,"a":17,"key":"67:17","ar":"أَمْ أَمِنتُم مَّن فِى ٱلسَّمَآءِ أَن يُرْسِلَ عَلَيْكُمْ حَاصِبًا ۖ فَسَتَعْلَمُونَ كَيْفَ نَذِيرِ","en":"Or do you feel secure that He who is above would not send against you a storm of stones? Then you would know how [severe] was My warning.","tr":"Am amintum man fee assama-ian yursila AAalaykum hasiban fasataAAlamoona kayfa natheer","juz":29,"page":563},{"s":67,"a":18,"key":"67:18","ar":"وَلَقَدْ كَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ فَكَيْفَ كَانَ نَكِيرِ","en":"And already had those before them denied, and how [terrible] was My reproach.","tr":"Walaqad kaththaba allatheenamin qablihim fakayfa kana nakeer","juz":29,"page":563},{"s":67,"a":19,"key":"67:19","ar":"أَوَلَمْ يَرَوْا۟ إِلَى ٱلطَّيْرِ فَوْقَهُمْ صَـٰٓفَّـٰتٍ وَيَقْبِضْنَ ۚ مَا يُمْسِكُهُنَّ إِلَّا ٱلرَّحْمَـٰنُ ۚ إِنَّهُۥ بِكُلِّ شَىْءٍۭ بَصِيرٌ","en":"Do they not see the birds above them with wings outspread and [sometimes] folded in? None holds them [aloft] except the Most Merciful. Indeed He is, of all things, Seeing.","tr":"Awa lam yaraw ila attayrifawqahum saffatin wayaqbidna mayumsikuhunna illa arrahmanu innahubikulli shay-in baseer","juz":29,"page":563},{"s":67,"a":20,"key":"67:20","ar":"أَمَّنْ هَـٰذَا ٱلَّذِى هُوَ جُندٌ لَّكُمْ يَنصُرُكُم مِّن دُونِ ٱلرَّحْمَـٰنِ ۚ إِنِ ٱلْكَـٰفِرُونَ إِلَّا فِى غُرُورٍ","en":"Or who is it that could be an army for you to aid you other than the Most Merciful? The disbelievers are not but in delusion.","tr":"Amman hatha allathee huwajundun lakum yansurukum min dooni arrahmaniini alkafiroona illa fee ghuroor","juz":29,"page":563},{"s":67,"a":21,"key":"67:21","ar":"أَمَّنْ هَـٰذَا ٱلَّذِى يَرْزُقُكُمْ إِنْ أَمْسَكَ رِزْقَهُۥ ۚ بَل لَّجُّوا۟ فِى عُتُوٍّ وَنُفُورٍ","en":"Or who is it that could provide for you if He withheld His provision? But they have persisted in insolence and aversion.","tr":"Amman hatha allatheeyarzuqukum in amsaka rizqahu bal lajjoo fee AAutuwwin wanufoor","juz":29,"page":563},{"s":67,"a":22,"key":"67:22","ar":"أَفَمَن يَمْشِى مُكِبًّا عَلَىٰ وَجْهِهِۦٓ أَهْدَىٰٓ أَمَّن يَمْشِى سَوِيًّا عَلَىٰ صِرَٰطٍ مُّسْتَقِيمٍ","en":"Then is one who walks fallen on his face better guided or one who walks erect on a straight path?","tr":"Afaman yamshee mukibban AAala wajhihiahda amman yamshee sawiyyan AAala siratinmustaqeem","juz":29,"page":563},{"s":67,"a":23,"key":"67:23","ar":"قُلْ هُوَ ٱلَّذِىٓ أَنشَأَكُمْ وَجَعَلَ لَكُمُ ٱلسَّمْعَ وَٱلْأَبْصَـٰرَ وَٱلْأَفْـِٔدَةَ ۖ قَلِيلًا مَّا تَشْكُرُونَ","en":"Say, \"It is He who has produced you and made for you hearing and vision and hearts [i.e., intellect]; little are you grateful.\"","tr":"Qul huwa allathee anshaakum wajaAAalalakumu assamAAa wal-absara wal-af-idataqaleelan ma tashkuroon","juz":29,"page":563},{"s":67,"a":24,"key":"67:24","ar":"قُلْ هُوَ ٱلَّذِى ذَرَأَكُمْ فِى ٱلْأَرْضِ وَإِلَيْهِ تُحْشَرُونَ","en":"Say, \"It is He who has multiplied you throughout the earth, and to Him you will be gathered.\"","tr":"Qul huwa allathee tharaakumfee al-ardi wa-ilayhi tuhsharoon","juz":29,"page":563},{"s":67,"a":25,"key":"67:25","ar":"وَيَقُولُونَ مَتَىٰ هَـٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَـٰدِقِينَ","en":"And they say, \"When is this promise, if you should be truthful?\"","tr":"Wayaqooloona mata hathaalwaAAdu in kuntum sadiqeen","juz":29,"page":563},{"s":67,"a":26,"key":"67:26","ar":"قُلْ إِنَّمَا ٱلْعِلْمُ عِندَ ٱللَّهِ وَإِنَّمَآ أَنَا۠ نَذِيرٌ مُّبِينٌ","en":"Say, \"The knowledge is only with Allāh, and I am only a clear warner.\"","tr":"Qul innama alAAilmu AAinda Allahiwa-innama ana natheerun mubeen","juz":29,"page":563},{"s":67,"a":27,"key":"67:27","ar":"فَلَمَّا رَأَوْهُ زُلْفَةً سِيٓـَٔتْ وُجُوهُ ٱلَّذِينَ كَفَرُوا۟ وَقِيلَ هَـٰذَا ٱلَّذِى كُنتُم بِهِۦ تَدَّعُونَ","en":"But when they see it1 approaching, the faces of those who disbelieve will be distressed, and it will be said, \"This is that for which you used to call.\"2","tr":"Falamma raawhu zulfatan see-atwujoohu allatheena kafaroo waqeela hatha allatheekuntum bihi taddaAAoon","juz":29,"page":564},{"s":67,"a":28,"key":"67:28","ar":"قُلْ أَرَءَيْتُمْ إِنْ أَهْلَكَنِىَ ٱللَّهُ وَمَن مَّعِىَ أَوْ رَحِمَنَا فَمَن يُجِيرُ ٱلْكَـٰفِرِينَ مِنْ عَذَابٍ أَلِيمٍ","en":"Say, [O Muḥammad], \"Have you considered:1 whether Allāh should cause my death and those with me or have mercy upon us, who can protect the disbelievers from a painful punishment?\"","tr":"Qul araaytum in ahlakaniya Allahuwaman maAAiya aw rahimana faman yujeeru alkafireenamin AAathabin aleem","juz":29,"page":564},{"s":67,"a":29,"key":"67:29","ar":"قُلْ هُوَ ٱلرَّحْمَـٰنُ ءَامَنَّا بِهِۦ وَعَلَيْهِ تَوَكَّلْنَا ۖ فَسَتَعْلَمُونَ مَنْ هُوَ فِى ضَلَـٰلٍ مُّبِينٍ","en":"Say, \"He is the Most Merciful; we have believed in Him, and upon Him we have relied. And you will [come to] know who it is that is in clear error.\"","tr":"Qul huwa arrahmanu amannabihi waAAalayhi tawakkalna fasataAAlamoona man huwa fee dalalinmubeen","juz":29,"page":564},{"s":67,"a":30,"key":"67:30","ar":"قُلْ أَرَءَيْتُمْ إِنْ أَصْبَحَ مَآؤُكُمْ غَوْرًا فَمَن يَأْتِيكُم بِمَآءٍ مَّعِينٍۭ","en":"Say, \"Have you considered: if your water was to become sunken [into the earth], then who could bring you flowing water?\"","tr":"Qul araaytum in asbaha maokumghawran faman ya/teekum bima-in maAAeen","juz":29,"page":564},{"s":68,"a":1,"key":"68:1","ar":" نٓ ۚ وَٱلْقَلَمِ وَمَا يَسْطُرُونَ","en":"Nūn.1 By the pen and what they inscribe,","tr":"Noon walqalami wama yasturoon","juz":29,"page":564},{"s":68,"a":2,"key":"68:2","ar":"مَآ أَنتَ بِنِعْمَةِ رَبِّكَ بِمَجْنُونٍ","en":"You are not, [O Muḥammad], by the favor of your Lord, a madman.","tr":"Ma anta biniAAmati rabbika bimajnoon","juz":29,"page":564},{"s":68,"a":3,"key":"68:3","ar":"وَإِنَّ لَكَ لَأَجْرًا غَيْرَ مَمْنُونٍ","en":"And indeed, for you is a reward uninterrupted.","tr":"Wa-inna laka laajran ghayra mamnoon","juz":29,"page":564},{"s":68,"a":4,"key":"68:4","ar":"وَإِنَّكَ لَعَلَىٰ خُلُقٍ عَظِيمٍ","en":"And indeed, you are of a great moral character.","tr":"Wa-innaka laAAala khuluqin AAatheem","juz":29,"page":564},{"s":68,"a":5,"key":"68:5","ar":"فَسَتُبْصِرُ وَيُبْصِرُونَ","en":"So you will see and they will see.","tr":"Fasatubsiru wayubsiroon","juz":29,"page":564},{"s":68,"a":6,"key":"68:6","ar":"بِأَييِّكُمُ ٱلْمَفْتُونُ","en":"Which of you is the afflicted [by a devil].","tr":"Bi-ayyikumu almaftoon","juz":29,"page":564},{"s":68,"a":7,"key":"68:7","ar":"إِنَّ رَبَّكَ هُوَ أَعْلَمُ بِمَن ضَلَّ عَن سَبِيلِهِۦ وَهُوَ أَعْلَمُ بِٱلْمُهْتَدِينَ","en":"Indeed, your Lord is most knowing of who has gone astray from His way, and He is most knowing of the [rightly] guided.","tr":"Inna rabbaka huwa aAAlamu biman dallaAAan sabeelihi wahuwa aAAlamu bilmuhtadeen","juz":29,"page":564},{"s":68,"a":8,"key":"68:8","ar":"فَلَا تُطِعِ ٱلْمُكَذِّبِينَ","en":"Then do not obey the deniers.","tr":"Fala tutiAAi almukaththibeen","juz":29,"page":564},{"s":68,"a":9,"key":"68:9","ar":"وَدُّوا۟ لَوْ تُدْهِنُ فَيُدْهِنُونَ","en":"They wish that you would soften [in your position], so they would soften [toward you].","tr":"Waddoo law tudhinu fayudhinoon","juz":29,"page":564},{"s":68,"a":10,"key":"68:10","ar":"وَلَا تُطِعْ كُلَّ حَلَّافٍ مَّهِينٍ","en":"And do not obey every worthless habitual swearer","tr":"Wala tutiAA kulla hallafinmaheen","juz":29,"page":564},{"s":68,"a":11,"key":"68:11","ar":"هَمَّازٍ مَّشَّآءٍۭ بِنَمِيمٍ","en":"[And] scorner, going about with malicious gossip -","tr":"Hammazin mashsha-in binameem","juz":29,"page":564},{"s":68,"a":12,"key":"68:12","ar":"مَّنَّاعٍ لِّلْخَيْرِ مُعْتَدٍ أَثِيمٍ","en":"A preventer of good, transgressing and sinful,","tr":"MannaAAin lilkhayri muAAtadin atheem","juz":29,"page":564},{"s":68,"a":13,"key":"68:13","ar":"عُتُلٍّۭ بَعْدَ ذَٰلِكَ زَنِيمٍ","en":"Cruel, moreover, and an illegitimate pretender.1","tr":"AAutullin baAAda thalika zaneem","juz":29,"page":564},{"s":68,"a":14,"key":"68:14","ar":"أَن كَانَ ذَا مَالٍ وَبَنِينَ","en":"Because he is a possessor of wealth and children,","tr":"An kana tha malinwabaneen","juz":29,"page":564},{"s":68,"a":15,"key":"68:15","ar":"إِذَا تُتْلَىٰ عَلَيْهِ ءَايَـٰتُنَا قَالَ أَسَـٰطِيرُ ٱلْأَوَّلِينَ","en":"When Our verses are recited to him, he says, \"Legends of the former peoples.\"","tr":"Itha tutla AAalayhi ayatunaqala asateeru al-awwaleen","juz":29,"page":564},{"s":68,"a":16,"key":"68:16","ar":"سَنَسِمُهُۥ عَلَى ٱلْخُرْطُومِ","en":"We will brand him upon the snout.1","tr":"Sanasimuhu AAala alkhurtoom","juz":29,"page":565},{"s":68,"a":17,"key":"68:17","ar":"إِنَّا بَلَوْنَـٰهُمْ كَمَا بَلَوْنَآ أَصْحَـٰبَ ٱلْجَنَّةِ إِذْ أَقْسَمُوا۟ لَيَصْرِمُنَّهَا مُصْبِحِينَ","en":"Indeed, We have tried them as We tried the companions of the garden, when they swore to cut its fruit in the [early] morning","tr":"Inna balawnahum kamabalawna as-haba aljannati ith aqsamoolayasrimunnaha musbiheen","juz":29,"page":565},{"s":68,"a":18,"key":"68:18","ar":"وَلَا يَسْتَثْنُونَ","en":"Without making exception.1","tr":"Wala yastathnoon","juz":29,"page":565},{"s":68,"a":19,"key":"68:19","ar":"فَطَافَ عَلَيْهَا طَآئِفٌ مِّن رَّبِّكَ وَهُمْ نَآئِمُونَ","en":"So there came upon it [i.e., the garden] an affliction from your Lord while they were asleep.","tr":"Fatafa AAalayha ta-ifunmin rabbika wahum na-imoon","juz":29,"page":565},{"s":68,"a":20,"key":"68:20","ar":"فَأَصْبَحَتْ كَٱلصَّرِيمِ","en":"And it became as though reaped.","tr":"Faasbahat kassareem","juz":29,"page":565},{"s":68,"a":21,"key":"68:21","ar":"فَتَنَادَوْا۟ مُصْبِحِينَ","en":"And they called one another at morning,","tr":"Fatanadaw musbiheen","juz":29,"page":565},{"s":68,"a":22,"key":"68:22","ar":"أَنِ ٱغْدُوا۟ عَلَىٰ حَرْثِكُمْ إِن كُنتُمْ صَـٰرِمِينَ","en":"[Saying], \"Go early to your crop if you would cut the fruit.\"","tr":"Ani ighdoo AAala harthikum inkuntum sarimeen","juz":29,"page":565},{"s":68,"a":23,"key":"68:23","ar":"فَٱنطَلَقُوا۟ وَهُمْ يَتَخَـٰفَتُونَ","en":"So they set out, while lowering their voices,","tr":"Fantalaqoo wahum yatakhafatoon","juz":29,"page":565},{"s":68,"a":24,"key":"68:24","ar":"أَن لَّا يَدْخُلَنَّهَا ٱلْيَوْمَ عَلَيْكُم مِّسْكِينٌ","en":"[Saying], \"There will surely not enter it today upon you [any] poor person.\"","tr":"An la yadkhulannaha alyawmaAAalaykum miskeen","juz":29,"page":565},{"s":68,"a":25,"key":"68:25","ar":"وَغَدَوْا۟ عَلَىٰ حَرْدٍ قَـٰدِرِينَ","en":"And they went early in determination, [assuming themselves] able.1","tr":"Waghadaw AAala hardin qadireen","juz":29,"page":565},{"s":68,"a":26,"key":"68:26","ar":"فَلَمَّا رَأَوْهَا قَالُوٓا۟ إِنَّا لَضَآلُّونَ","en":"But when they saw it, they said, \"Indeed, we are lost;","tr":"Falamma raawha qalooinna ladalloon","juz":29,"page":565},{"s":68,"a":27,"key":"68:27","ar":"بَلْ نَحْنُ مَحْرُومُونَ","en":"Rather, we have been deprived.\"","tr":"Bal nahnu mahroomoon","juz":29,"page":565},{"s":68,"a":28,"key":"68:28","ar":"قَالَ أَوْسَطُهُمْ أَلَمْ أَقُل لَّكُمْ لَوْلَا تُسَبِّحُونَ","en":"The most moderate of them said, \"Did I not say to you, 'Why do you not exalt [Allāh]?'\"1","tr":"Qala awsatuhum alam aqul lakumlawla tusabbihoon","juz":29,"page":565},{"s":68,"a":29,"key":"68:29","ar":"قَالُوا۟ سُبْحَـٰنَ رَبِّنَآ إِنَّا كُنَّا ظَـٰلِمِينَ","en":"They said, \"Exalted is our Lord! Indeed, we were wrongdoers.\"","tr":"Qaloo subhana rabbinainna kunna thalimeen","juz":29,"page":565},{"s":68,"a":30,"key":"68:30","ar":"فَأَقْبَلَ بَعْضُهُمْ عَلَىٰ بَعْضٍ يَتَلَـٰوَمُونَ","en":"Then they approached one another, blaming each other.","tr":"Faaqbala baAAduhum AAala baAAdinyatalawamoon","juz":29,"page":565},{"s":68,"a":31,"key":"68:31","ar":"قَالُوا۟ يَـٰوَيْلَنَآ إِنَّا كُنَّا طَـٰغِينَ","en":"They said, \"O woe to us; indeed we were transgressors.","tr":"Qaloo ya waylana innakunna tagheen","juz":29,"page":565},{"s":68,"a":32,"key":"68:32","ar":"عَسَىٰ رَبُّنَآ أَن يُبْدِلَنَا خَيْرًا مِّنْهَآ إِنَّآ إِلَىٰ رَبِّنَا رَٰغِبُونَ","en":"Perhaps our Lord will substitute for us [one] better than it. Indeed, we are toward our Lord desirous.\"1","tr":"AAasa rabbuna an yubdilanakhayran minha inna ila rabbina raghiboon","juz":29,"page":565},{"s":68,"a":33,"key":"68:33","ar":"كَذَٰلِكَ ٱلْعَذَابُ ۖ وَلَعَذَابُ ٱلْـَٔاخِرَةِ أَكْبَرُ ۚ لَوْ كَانُوا۟ يَعْلَمُونَ","en":"Such is the punishment [of this world]. And the punishment of the Hereafter is greater, if they only knew.","tr":"Kathalika alAAathabu walaAAathabual-akhirati akbaru law kanoo yaAAlamoon","juz":29,"page":565},{"s":68,"a":34,"key":"68:34","ar":"إِنَّ لِلْمُتَّقِينَ عِندَ رَبِّهِمْ جَنَّـٰتِ ٱلنَّعِيمِ","en":"Indeed, for the righteous with their Lord are the Gardens of Pleasure.","tr":"Inna lilmuttaqeena AAinda rabbihim jannatiannaAAeem","juz":29,"page":565},{"s":68,"a":35,"key":"68:35","ar":"أَفَنَجْعَلُ ٱلْمُسْلِمِينَ كَٱلْمُجْرِمِينَ","en":"Then will We treat the Muslims like the criminals?","tr":"AfanajAAalu almuslimeena kalmujrimeen","juz":29,"page":565},{"s":68,"a":36,"key":"68:36","ar":"مَا لَكُمْ كَيْفَ تَحْكُمُونَ","en":"What is [the matter] with you? How do you judge?","tr":"Ma lakum kayfa tahkumoon","juz":29,"page":565},{"s":68,"a":37,"key":"68:37","ar":"أَمْ لَكُمْ كِتَـٰبٌ فِيهِ تَدْرُسُونَ","en":"Or do you have a scripture in which you learn","tr":"Am lakum kitabun feehi tadrusoon","juz":29,"page":565},{"s":68,"a":38,"key":"68:38","ar":"إِنَّ لَكُمْ فِيهِ لَمَا تَخَيَّرُونَ","en":"That indeed for you is whatever you choose?","tr":"Inna lakum feehi lama takhayyaroon","juz":29,"page":565},{"s":68,"a":39,"key":"68:39","ar":"أَمْ لَكُمْ أَيْمَـٰنٌ عَلَيْنَا بَـٰلِغَةٌ إِلَىٰ يَوْمِ ٱلْقِيَـٰمَةِ ۙ إِنَّ لَكُمْ لَمَا تَحْكُمُونَ","en":"Or do you have oaths [binding] upon Us, extending until the Day of Resurrection, that indeed for you is whatever you judge?","tr":"Am lakum aymanun AAalayna balighatunila yawmi alqiyamati inna lakum lama tahkumoon","juz":29,"page":565},{"s":68,"a":40,"key":"68:40","ar":"سَلْهُمْ أَيُّهُم بِذَٰلِكَ زَعِيمٌ","en":"Ask them which of them, for that [claim], is responsible.","tr":"Salhum ayyuhum bithalika zaAAeem","juz":29,"page":565},{"s":68,"a":41,"key":"68:41","ar":"أَمْ لَهُمْ شُرَكَآءُ فَلْيَأْتُوا۟ بِشُرَكَآئِهِمْ إِن كَانُوا۟ صَـٰدِقِينَ","en":"Or do they have partners?1 Then let them bring their partners, if they should be truthful.","tr":"Am lahum shurakao falya/too bishuraka-ihimin kanoo sadiqeen","juz":29,"page":565},{"s":68,"a":42,"key":"68:42","ar":"يَوْمَ يُكْشَفُ عَن سَاقٍ وَيُدْعَوْنَ إِلَى ٱلسُّجُودِ فَلَا يَسْتَطِيعُونَ","en":"The Day the shin will be uncovered1 and they are invited to prostration but they [i.e., the disbelievers] will not be able,","tr":"Yawma yukshafu AAan saqin wayudAAawnaila assujoodi fala yastateeAAoon","juz":29,"page":565},{"s":68,"a":43,"key":"68:43","ar":"خَـٰشِعَةً أَبْصَـٰرُهُمْ تَرْهَقُهُمْ ذِلَّةٌ ۖ وَقَدْ كَانُوا۟ يُدْعَوْنَ إِلَى ٱلسُّجُودِ وَهُمْ سَـٰلِمُونَ","en":"Their eyes humbled, humiliation will cover them. And they used to be invited to prostration while they were sound.1","tr":"KhashiAAatan absaruhumtarhaquhum thillatun waqad kanoo yudAAawna ilaassujoodi wahum salimoon","juz":29,"page":566},{"s":68,"a":44,"key":"68:44","ar":"فَذَرْنِى وَمَن يُكَذِّبُ بِهَـٰذَا ٱلْحَدِيثِ ۖ سَنَسْتَدْرِجُهُم مِّنْ حَيْثُ لَا يَعْلَمُونَ","en":"So leave Me, [O Muḥammad], with [the matter of] whoever denies this statement [i.e., the Qur’ān]. We will progressively lead them [to punishment] from where they do not know.1","tr":"Fatharnee waman yukaththibubihatha alhadeethi sanastadrijuhum min haythula yaAAlamoon","juz":29,"page":566},{"s":68,"a":45,"key":"68:45","ar":"وَأُمْلِى لَهُمْ ۚ إِنَّ كَيْدِى مَتِينٌ","en":"And I will give them time. Indeed, My plan is firm.","tr":"Waomlee lahum inna kaydee mateen","juz":29,"page":566},{"s":68,"a":46,"key":"68:46","ar":"أَمْ تَسْـَٔلُهُمْ أَجْرًا فَهُم مِّن مَّغْرَمٍ مُّثْقَلُونَ","en":"Or do you ask of them a payment, so they are by debt burdened down?","tr":"Am tas-aluhum ajran fahum min maghraminmuthqaloon","juz":29,"page":566},{"s":68,"a":47,"key":"68:47","ar":"أَمْ عِندَهُمُ ٱلْغَيْبُ فَهُمْ يَكْتُبُونَ","en":"Or have they [knowledge of] the unseen, so they write [it] down?","tr":"Am AAindahumu alghaybu fahum yaktuboon","juz":29,"page":566},{"s":68,"a":48,"key":"68:48","ar":"فَٱصْبِرْ لِحُكْمِ رَبِّكَ وَلَا تَكُن كَصَاحِبِ ٱلْحُوتِ إِذْ نَادَىٰ وَهُوَ مَكْظُومٌ","en":"Then be patient for the decision of your Lord, [O Muḥammad], and be not like the companion of the fish [i.e., Jonah] when he called out while he was distressed.","tr":"Fasbir lihukmi rabbikawala takun kasahibi alhooti ith nadawahuwa makthoom","juz":29,"page":566},{"s":68,"a":49,"key":"68:49","ar":"لَّوْلَآ أَن تَدَٰرَكَهُۥ نِعْمَةٌ مِّن رَّبِّهِۦ لَنُبِذَ بِٱلْعَرَآءِ وَهُوَ مَذْمُومٌ","en":"If not that a favor [i.e., mercy] from his Lord overtook him, he would have been thrown onto the naked shore while he was censured.1","tr":"Lawla an tadarakahu niAAmatunmin rabbihi lanubitha bilAAara-i wahuwa mathmoom","juz":29,"page":566},{"s":68,"a":50,"key":"68:50","ar":"فَٱجْتَبَـٰهُ رَبُّهُۥ فَجَعَلَهُۥ مِنَ ٱلصَّـٰلِحِينَ","en":"And his Lord chose him and made him of the righteous.","tr":"Fajtabahu rabbuhu fajaAAalahumina assaliheen","juz":29,"page":566},{"s":68,"a":51,"key":"68:51","ar":"وَإِن يَكَادُ ٱلَّذِينَ كَفَرُوا۟ لَيُزْلِقُونَكَ بِأَبْصَـٰرِهِمْ لَمَّا سَمِعُوا۟ ٱلذِّكْرَ وَيَقُولُونَ إِنَّهُۥ لَمَجْنُونٌ","en":"And indeed, those who disbelieve would almost make you slip with their eyes [i.e., looks] when they hear the message, and they say, \"Indeed, he is mad.\"","tr":"Wa-in yakadu allatheenakafaroo layuzliqoonaka bi-absarihim lamma samiAAooaththikra wayaqooloona innahu lamajnoon","juz":29,"page":566},{"s":68,"a":52,"key":"68:52","ar":"وَمَا هُوَ إِلَّا ذِكْرٌ لِّلْعَـٰلَمِينَ","en":"But it is not except a reminder to the worlds.","tr":"Wama huwa illa thikrunlilAAalameen","juz":29,"page":566},{"s":69,"a":1,"key":"69:1","ar":" ٱلْحَآقَّةُ","en":"The Inevitable Reality -","tr":"Alhaqqa","juz":29,"page":566},{"s":69,"a":2,"key":"69:2","ar":"مَا ٱلْحَآقَّةُ","en":"What is the Inevitable Reality?","tr":"Ma alhaqqa","juz":29,"page":566},{"s":69,"a":3,"key":"69:3","ar":"وَمَآ أَدْرَىٰكَ مَا ٱلْحَآقَّةُ","en":"And what can make you know what is the Inevitable Reality?","tr":"Wama adraka ma alhaqqa","juz":29,"page":566},{"s":69,"a":4,"key":"69:4","ar":"كَذَّبَتْ ثَمُودُ وَعَادٌۢ بِٱلْقَارِعَةِ","en":"Thamūd and ʿAad denied the Striking Calamity [i.e., the Resurrection].","tr":"Kaththabat thamoodu waAAadun bilqariAAa","juz":29,"page":566},{"s":69,"a":5,"key":"69:5","ar":"فَأَمَّا ثَمُودُ فَأُهْلِكُوا۟ بِٱلطَّاغِيَةِ","en":"So as for Thamūd, they were destroyed by the overpowering [blast].","tr":"Faamma thamoodu faohlikoo bittaghiya","juz":29,"page":566},{"s":69,"a":6,"key":"69:6","ar":"وَأَمَّا عَادٌ فَأُهْلِكُوا۟ بِرِيحٍ صَرْصَرٍ عَاتِيَةٍ","en":"And as for ʿAad, they were destroyed by a screaming,1 violent wind","tr":"Waamma AAadun faohlikoo bireehinsarsarin AAatiya","juz":29,"page":566},{"s":69,"a":7,"key":"69:7","ar":"سَخَّرَهَا عَلَيْهِمْ سَبْعَ لَيَالٍ وَثَمَـٰنِيَةَ أَيَّامٍ حُسُومًا فَتَرَى ٱلْقَوْمَ فِيهَا صَرْعَىٰ كَأَنَّهُمْ أَعْجَازُ نَخْلٍ خَاوِيَةٍ","en":"Which He [i.e., Allāh] imposed upon them for seven nights and eight days in succession, so you would see the people therein fallen as if they were hollow trunks of palm trees.","tr":"Sakhkharaha AAalayhim sabAAa layalinwathamaniyata ayyamin husooman fataraalqawma feeha sarAAa kaannahum aAAjazunakhlin khawiya","juz":29,"page":566},{"s":69,"a":8,"key":"69:8","ar":"فَهَلْ تَرَىٰ لَهُم مِّنۢ بَاقِيَةٍ","en":"Then do you see of them any remains?","tr":"Fahal tara lahum min baqiya","juz":29,"page":566},{"s":69,"a":9,"key":"69:9","ar":"وَجَآءَ فِرْعَوْنُ وَمَن قَبْلَهُۥ وَٱلْمُؤْتَفِكَـٰتُ بِٱلْخَاطِئَةِ","en":"And there came Pharaoh and those before him and the overturned cities1 with sin.","tr":"Wajaa firAAawnu waman qablahu walmu/tafikatubilkhati-a","juz":29,"page":567},{"s":69,"a":10,"key":"69:10","ar":"فَعَصَوْا۟ رَسُولَ رَبِّهِمْ فَأَخَذَهُمْ أَخْذَةً رَّابِيَةً","en":"And they disobeyed the messenger of their Lord, so He seized them with a seizure exceeding [in severity].","tr":"FaAAasaw rasoola rabbihim faakhathahumakhthatan rabiya","juz":29,"page":567},{"s":69,"a":11,"key":"69:11","ar":"إِنَّا لَمَّا طَغَا ٱلْمَآءُ حَمَلْنَـٰكُمْ فِى ٱلْجَارِيَةِ","en":"Indeed, when the water overflowed, We carried you [i.e., your ancestors] in the sailing ship1","tr":"Inna lamma taghaalmao hamalnakum fee aljariya","juz":29,"page":567},{"s":69,"a":12,"key":"69:12","ar":"لِنَجْعَلَهَا لَكُمْ تَذْكِرَةً وَتَعِيَهَآ أُذُنٌ وَٰعِيَةٌ","en":"That We might make it for you a reminder and [that] a conscious ear would be conscious of it.","tr":"LinajAAalaha lakum tathkiratanwataAAiyaha othunun waAAiya","juz":29,"page":567},{"s":69,"a":13,"key":"69:13","ar":"فَإِذَا نُفِخَ فِى ٱلصُّورِ نَفْخَةٌ وَٰحِدَةٌ","en":"Then when the Horn is blown with one blast","tr":"Fa-itha nufikha fee assoorinafkhatun wahida","juz":29,"page":567},{"s":69,"a":14,"key":"69:14","ar":"وَحُمِلَتِ ٱلْأَرْضُ وَٱلْجِبَالُ فَدُكَّتَا دَكَّةً وَٰحِدَةً","en":"And the earth and the mountains are lifted and leveled with one blow [i.e., stroke] -","tr":"Wahumilati al-ardu waljibalufadukkata dakkatan wahida","juz":29,"page":567},{"s":69,"a":15,"key":"69:15","ar":"فَيَوْمَئِذٍ وَقَعَتِ ٱلْوَاقِعَةُ","en":"Then on that Day, the Occurrence [i.e., Resurrection] will occur,","tr":"Fayawma-ithin waqaAAati alwaqiAAa","juz":29,"page":567},{"s":69,"a":16,"key":"69:16","ar":"وَٱنشَقَّتِ ٱلسَّمَآءُ فَهِىَ يَوْمَئِذٍ وَاهِيَةٌ","en":"And the heaven will split [open], for that Day it is infirm.1","tr":"Wanshaqqati assamaofahiya yawma-ithin wahiya","juz":29,"page":567},{"s":69,"a":17,"key":"69:17","ar":"وَٱلْمَلَكُ عَلَىٰٓ أَرْجَآئِهَا ۚ وَيَحْمِلُ عَرْشَ رَبِّكَ فَوْقَهُمْ يَوْمَئِذٍ ثَمَـٰنِيَةٌ","en":"And the angels are at its edges. And there will bear the Throne of your Lord above them, that Day, eight [of them].","tr":"Walmalaku AAala arja-ihawayahmilu AAarsha rabbika fawqahum yawma-ithin thamaniya","juz":29,"page":567},{"s":69,"a":18,"key":"69:18","ar":"يَوْمَئِذٍ تُعْرَضُونَ لَا تَخْفَىٰ مِنكُمْ خَافِيَةٌ","en":"That Day, you will be exhibited [for judgement]; not hidden among you is anything concealed.1","tr":"Yawma-ithin tuAAradoona latakhfa minkum khafiya","juz":29,"page":567},{"s":69,"a":19,"key":"69:19","ar":"فَأَمَّا مَنْ أُوتِىَ كِتَـٰبَهُۥ بِيَمِينِهِۦ فَيَقُولُ هَآؤُمُ ٱقْرَءُوا۟ كِتَـٰبِيَهْ","en":"So as for he who is given his record in his right hand, he will say, \"Here, read my record!","tr":"Faamma man ootiya kitabahubiyameenihi fayaqoolu haomu iqraoo kitabiyah","juz":29,"page":567},{"s":69,"a":20,"key":"69:20","ar":"إِنِّى ظَنَنتُ أَنِّى مُلَـٰقٍ حِسَابِيَهْ","en":"Indeed, I was certain that I would be meeting my account.\"","tr":"Innee thanantu annee mulaqinhisabiyah","juz":29,"page":567},{"s":69,"a":21,"key":"69:21","ar":"فَهُوَ فِى عِيشَةٍ رَّاضِيَةٍ","en":"So he will be in a pleasant life -","tr":"Fahuwa fee AAeeshatin radiya","juz":29,"page":567},{"s":69,"a":22,"key":"69:22","ar":"فِى جَنَّةٍ عَالِيَةٍ","en":"In an elevated garden,","tr":"Fee jannatin AAaliya","juz":29,"page":567},{"s":69,"a":23,"key":"69:23","ar":"قُطُوفُهَا دَانِيَةٌ","en":"Its [fruit] to be picked hanging near.","tr":"Qutoofuha daniya","juz":29,"page":567},{"s":69,"a":24,"key":"69:24","ar":"كُلُوا۟ وَٱشْرَبُوا۟ هَنِيٓـًٔۢا بِمَآ أَسْلَفْتُمْ فِى ٱلْأَيَّامِ ٱلْخَالِيَةِ","en":"[They will be told], \"Eat and drink in satisfaction for what you put forth1 in the days past.\"","tr":"Kuloo washraboo hanee-an bimaaslaftum fee al-ayyami alkhaliya","juz":29,"page":567},{"s":69,"a":25,"key":"69:25","ar":"وَأَمَّا مَنْ أُوتِىَ كِتَـٰبَهُۥ بِشِمَالِهِۦ فَيَقُولُ يَـٰلَيْتَنِى لَمْ أُوتَ كِتَـٰبِيَهْ","en":"But as for he who is given his record in his left hand, he will say, \"Oh, I wish I had not been given my record","tr":"Waamma man ootiya kitabahubishimalihi fayaqoolu ya laytanee lam oota kitabiyah","juz":29,"page":567},{"s":69,"a":26,"key":"69:26","ar":"وَلَمْ أَدْرِ مَا حِسَابِيَهْ","en":"And had not known what is my account.","tr":"Walam adri ma hisabiyah","juz":29,"page":567},{"s":69,"a":27,"key":"69:27","ar":"يَـٰلَيْتَهَا كَانَتِ ٱلْقَاضِيَةَ","en":"I wish it [i.e., my death] had been the decisive one.1","tr":"Ya laytaha kanati alqadiya","juz":29,"page":567},{"s":69,"a":28,"key":"69:28","ar":"مَآ أَغْنَىٰ عَنِّى مَالِيَهْ ۜ","en":"My wealth has not availed me.","tr":"Ma aghna AAannee maliyah","juz":29,"page":567},{"s":69,"a":29,"key":"69:29","ar":"هَلَكَ عَنِّى سُلْطَـٰنِيَهْ","en":"Gone from me is my authority.\"1","tr":"Halaka AAannee sultaniyah","juz":29,"page":567},{"s":69,"a":30,"key":"69:30","ar":"خُذُوهُ فَغُلُّوهُ","en":"[Allāh will say], \"Seize him and shackle him.","tr":"Khuthoohu faghullooh","juz":29,"page":567},{"s":69,"a":31,"key":"69:31","ar":"ثُمَّ ٱلْجَحِيمَ صَلُّوهُ","en":"Then into Hellfire drive him.","tr":"Thumma aljaheema sallooh","juz":29,"page":567},{"s":69,"a":32,"key":"69:32","ar":"ثُمَّ فِى سِلْسِلَةٍ ذَرْعُهَا سَبْعُونَ ذِرَاعًا فَٱسْلُكُوهُ","en":"Then into a chain whose length is seventy cubits insert him.\"","tr":"Thumma fee silsilatin tharAAuhasabAAoona thiraAAan faslukooh","juz":29,"page":567},{"s":69,"a":33,"key":"69:33","ar":"إِنَّهُۥ كَانَ لَا يُؤْمِنُ بِٱللَّهِ ٱلْعَظِيمِ","en":"Indeed, he did not used to believe in Allāh, the Most Great,","tr":"Innahu kana la yu/minu billahialAAatheem","juz":29,"page":567},{"s":69,"a":34,"key":"69:34","ar":"وَلَا يَحُضُّ عَلَىٰ طَعَامِ ٱلْمِسْكِينِ","en":"Nor did he encourage the feeding of the poor.","tr":"Wala yahuddu AAalataAAami almiskeen","juz":29,"page":567},{"s":69,"a":35,"key":"69:35","ar":"فَلَيْسَ لَهُ ٱلْيَوْمَ هَـٰهُنَا حَمِيمٌ","en":"So there is not for him here this Day any devoted friend","tr":"Falaysa lahu alyawma hahuna hameem","juz":29,"page":568},{"s":69,"a":36,"key":"69:36","ar":"وَلَا طَعَامٌ إِلَّا مِنْ غِسْلِينٍ","en":"Nor any food except from the discharge of wounds;","tr":"Wala taAAamun illamin ghisleen","juz":29,"page":568},{"s":69,"a":37,"key":"69:37","ar":"لَّا يَأْكُلُهُۥٓ إِلَّا ٱلْخَـٰطِـُٔونَ","en":"None will eat it except the sinners.","tr":"La ya/kuluhu illa alkhati-oon","juz":29,"page":568},{"s":69,"a":38,"key":"69:38","ar":"فَلَآ أُقْسِمُ بِمَا تُبْصِرُونَ","en":"So I swear by what you see","tr":"Fala oqsimu bima tubsiroon","juz":29,"page":568},{"s":69,"a":39,"key":"69:39","ar":"وَمَا لَا تُبْصِرُونَ","en":"And what you do not see","tr":"Wama la tubsiroon","juz":29,"page":568},{"s":69,"a":40,"key":"69:40","ar":"إِنَّهُۥ لَقَوْلُ رَسُولٍ كَرِيمٍ","en":"[That] indeed, it [i.e., the Qur’ān] is the word of a noble Messenger.","tr":"Innahu laqawlu rasoolin kareem","juz":29,"page":568},{"s":69,"a":41,"key":"69:41","ar":"وَمَا هُوَ بِقَوْلِ شَاعِرٍ ۚ قَلِيلًا مَّا تُؤْمِنُونَ","en":"And it is not the word of a poet; little do you believe.","tr":"Wama huwa biqawli shaAAirinqaleelan ma tu/minoon","juz":29,"page":568},{"s":69,"a":42,"key":"69:42","ar":"وَلَا بِقَوْلِ كَاهِنٍ ۚ قَلِيلًا مَّا تَذَكَّرُونَ","en":"Nor the word of a soothsayer; little do you remember.","tr":"Wala biqawli kahinin qaleelanma tathakkaroon","juz":29,"page":568},{"s":69,"a":43,"key":"69:43","ar":"تَنزِيلٌ مِّن رَّبِّ ٱلْعَـٰلَمِينَ","en":"[It is] a revelation from the Lord of the worlds.","tr":"Tanzeelun min rabbi alAAalameen","juz":29,"page":568},{"s":69,"a":44,"key":"69:44","ar":"وَلَوْ تَقَوَّلَ عَلَيْنَا بَعْضَ ٱلْأَقَاوِيلِ","en":"And if he [i.e., Muḥammad] had made up about Us some [false] sayings,","tr":"Walaw taqawwala AAalayna baAAdaal-aqaweel","juz":29,"page":568},{"s":69,"a":45,"key":"69:45","ar":"لَأَخَذْنَا مِنْهُ بِٱلْيَمِينِ","en":"We would have seized him by the right hand;1","tr":"Laakhathna minhu bilyameen","juz":29,"page":568},{"s":69,"a":46,"key":"69:46","ar":"ثُمَّ لَقَطَعْنَا مِنْهُ ٱلْوَتِينَ","en":"Then We would have cut from him the aorta.1","tr":"Thumma laqataAAna minhualwateen","juz":29,"page":568},{"s":69,"a":47,"key":"69:47","ar":"فَمَا مِنكُم مِّنْ أَحَدٍ عَنْهُ حَـٰجِزِينَ","en":"And there is no one of you who could prevent [Us] from him.","tr":"Fama minkum min ahadin AAanhu hajizeen","juz":29,"page":568},{"s":69,"a":48,"key":"69:48","ar":"وَإِنَّهُۥ لَتَذْكِرَةٌ لِّلْمُتَّقِينَ","en":"And indeed, it [i.e., the Qur’ān] is a reminder for the righteous.","tr":"Wa-innahu latathkiratun lilmuttaqeen","juz":29,"page":568},{"s":69,"a":49,"key":"69:49","ar":"وَإِنَّا لَنَعْلَمُ أَنَّ مِنكُم مُّكَذِّبِينَ","en":"And indeed, We know that among you are deniers.","tr":"Wa-inna lanaAAlamu anna minkum mukaththibeen","juz":29,"page":568},{"s":69,"a":50,"key":"69:50","ar":"وَإِنَّهُۥ لَحَسْرَةٌ عَلَى ٱلْكَـٰفِرِينَ","en":"And indeed, it will be [a cause of] regret upon the disbelievers.","tr":"Wa-innahu lahasratun AAala alkafireen","juz":29,"page":568},{"s":69,"a":51,"key":"69:51","ar":"وَإِنَّهُۥ لَحَقُّ ٱلْيَقِينِ","en":"And indeed, it is the truth of certainty.","tr":"Wa-innahu lahaqqu alyaqeen","juz":29,"page":568},{"s":69,"a":52,"key":"69:52","ar":"فَسَبِّحْ بِٱسْمِ رَبِّكَ ٱلْعَظِيمِ","en":"So exalt the name of your Lord, the Most Great.","tr":"Fasabbih bismi rabbika alAAatheem","juz":29,"page":568},{"s":70,"a":1,"key":"70:1","ar":" سَأَلَ سَآئِلٌۢ بِعَذَابٍ وَاقِعٍ","en":"A supplicant asked for a punishment bound to happen1","tr":"Saala sa-ilun biAAathabin waqiAA","juz":29,"page":568},{"s":70,"a":2,"key":"70:2","ar":"لِّلْكَـٰفِرِينَ لَيْسَ لَهُۥ دَافِعٌ","en":"To the disbelievers; of it there is no preventer.","tr":"Lilkafireena laysa lahu dafiAA","juz":29,"page":568},{"s":70,"a":3,"key":"70:3","ar":"مِّنَ ٱللَّهِ ذِى ٱلْمَعَارِجِ","en":"[It is] from Allāh, owner of the ways of ascent.","tr":"Mina Allahi thee almaAAarij","juz":29,"page":568},{"s":70,"a":4,"key":"70:4","ar":"تَعْرُجُ ٱلْمَلَـٰٓئِكَةُ وَٱلرُّوحُ إِلَيْهِ فِى يَوْمٍ كَانَ مِقْدَارُهُۥ خَمْسِينَ أَلْفَ سَنَةٍ","en":"The angels and the Spirit [i.e., Gabriel] will ascend to Him during a Day the extent of which is fifty thousand years.","tr":"TaAAruju almala-ikatu warroohuilayhi fee yawmin kana miqdaruhu khamseena alfasana","juz":29,"page":568},{"s":70,"a":5,"key":"70:5","ar":"فَٱصْبِرْ صَبْرًا جَمِيلًا","en":"So be patient with gracious patience.","tr":"Fasbir sabran jameela","juz":29,"page":568},{"s":70,"a":6,"key":"70:6","ar":"إِنَّهُمْ يَرَوْنَهُۥ بَعِيدًا","en":"Indeed, they see it [as] distant,","tr":"Innahum yarawnahu baAAeeda","juz":29,"page":568},{"s":70,"a":7,"key":"70:7","ar":"وَنَرَىٰهُ قَرِيبًا","en":"But We see it [as] near.","tr":"Wanarahu qareeba","juz":29,"page":568},{"s":70,"a":8,"key":"70:8","ar":"يَوْمَ تَكُونُ ٱلسَّمَآءُ كَٱلْمُهْلِ","en":"On the Day the sky will be like murky oil,1","tr":"Yawma takoonu assamao kalmuhl","juz":29,"page":568},{"s":70,"a":9,"key":"70:9","ar":"وَتَكُونُ ٱلْجِبَالُ كَٱلْعِهْنِ","en":"And the mountains will be like wool,1","tr":"Watakoonu aljibalu kalAAihn","juz":29,"page":568},{"s":70,"a":10,"key":"70:10","ar":"وَلَا يَسْـَٔلُ حَمِيمٌ حَمِيمًا","en":"And no friend will ask [anything of] a friend,","tr":"Wala yas-alu hameemun hameema","juz":29,"page":568},{"s":70,"a":11,"key":"70:11","ar":"يُبَصَّرُونَهُمْ ۚ يَوَدُّ ٱلْمُجْرِمُ لَوْ يَفْتَدِى مِنْ عَذَابِ يَوْمِئِذٍۭ بِبَنِيهِ","en":"They will be shown each other. The criminal will wish that he could be ransomed from the punishment of that Day by his children.","tr":"Yubassaroonahum yawaddu almujrimu lawyaftadee min AAathabi yawmi-ithin bibaneeh","juz":29,"page":569},{"s":70,"a":12,"key":"70:12","ar":"وَصَـٰحِبَتِهِۦ وَأَخِيهِ","en":"And his wife and his brother","tr":"Wasahibatihi waakheeh","juz":29,"page":569},{"s":70,"a":13,"key":"70:13","ar":"وَفَصِيلَتِهِ ٱلَّتِى تُـْٔوِيهِ","en":"And his nearest kindred who shelter him.","tr":"Wafaseelatihi allatee tu/weeh","juz":29,"page":569},{"s":70,"a":14,"key":"70:14","ar":"وَمَن فِى ٱلْأَرْضِ جَمِيعًا ثُمَّ يُنجِيهِ","en":"And whoever is on earth entirely [so] then it could save him.","tr":"Waman fee al-ardi jameeAAan thummayunjeeh","juz":29,"page":569},{"s":70,"a":15,"key":"70:15","ar":"كَلَّآ ۖ إِنَّهَا لَظَىٰ","en":"No!1 Indeed, it is the Flame [of Hell],","tr":"Kalla innaha latha","juz":29,"page":569},{"s":70,"a":16,"key":"70:16","ar":"نَزَّاعَةً لِّلشَّوَىٰ","en":"A remover of exteriors.1","tr":"NazzaAAatan lishshawa","juz":29,"page":569},{"s":70,"a":17,"key":"70:17","ar":"تَدْعُوا۟ مَنْ أَدْبَرَ وَتَوَلَّىٰ","en":"It invites he who turned his back [on truth] and went away [from obedience]","tr":"TadAAoo man adbara watawalla","juz":29,"page":569},{"s":70,"a":18,"key":"70:18","ar":"وَجَمَعَ فَأَوْعَىٰٓ","en":"And collected [wealth] and hoarded.","tr":"WajamaAAa faawAAa","juz":29,"page":569},{"s":70,"a":19,"key":"70:19","ar":"۞ إِنَّ ٱلْإِنسَـٰنَ خُلِقَ هَلُوعًا","en":"Indeed, mankind was created anxious:","tr":"Inna al-insana khuliqa halooAAa","juz":29,"page":569},{"s":70,"a":20,"key":"70:20","ar":"إِذَا مَسَّهُ ٱلشَّرُّ جَزُوعًا","en":"When evil touches him, impatient,","tr":"Itha massahu ashsharrujazooAAa","juz":29,"page":569},{"s":70,"a":21,"key":"70:21","ar":"وَإِذَا مَسَّهُ ٱلْخَيْرُ مَنُوعًا","en":"And when good touches him, withholding [of it],","tr":"Wa-itha massahu alkhayru manooAAa","juz":29,"page":569},{"s":70,"a":22,"key":"70:22","ar":"إِلَّا ٱلْمُصَلِّينَ","en":"Except the observers of prayer -","tr":"Illa almusalleen","juz":29,"page":569},{"s":70,"a":23,"key":"70:23","ar":"ٱلَّذِينَ هُمْ عَلَىٰ صَلَاتِهِمْ دَآئِمُونَ","en":"Those who are constant in their prayer","tr":"Allatheena hum AAala salatihimda-imoon","juz":29,"page":569},{"s":70,"a":24,"key":"70:24","ar":"وَٱلَّذِينَ فِىٓ أَمْوَٰلِهِمْ حَقٌّ مَّعْلُومٌ","en":"And those within whose wealth is a known right1","tr":"Wallatheena fee amwalihimhaqqun maAAloom","juz":29,"page":569},{"s":70,"a":25,"key":"70:25","ar":"لِّلسَّآئِلِ وَٱلْمَحْرُومِ","en":"For the petitioner and the deprived -","tr":"Lissa-ili walmahroom","juz":29,"page":569},{"s":70,"a":26,"key":"70:26","ar":"وَٱلَّذِينَ يُصَدِّقُونَ بِيَوْمِ ٱلدِّينِ","en":"And those who believe in the Day of Recompense","tr":"Wallatheena yusaddiqoonabiyawmi addeen","juz":29,"page":569},{"s":70,"a":27,"key":"70:27","ar":"وَٱلَّذِينَ هُم مِّنْ عَذَابِ رَبِّهِم مُّشْفِقُونَ","en":"And those who are fearful of the punishment of their Lord -","tr":"Wallatheena hum min AAathabirabbihim mushfiqoon","juz":29,"page":569},{"s":70,"a":28,"key":"70:28","ar":"إِنَّ عَذَابَ رَبِّهِمْ غَيْرُ مَأْمُونٍ","en":"Indeed, the punishment of their Lord is not that from which one is safe -","tr":"Inna AAathaba rabbihim ghayru ma/moon","juz":29,"page":569},{"s":70,"a":29,"key":"70:29","ar":"وَٱلَّذِينَ هُمْ لِفُرُوجِهِمْ حَـٰفِظُونَ","en":"And those who guard their private parts","tr":"Wallatheena hum lifuroojihim hafithoon","juz":29,"page":569},{"s":70,"a":30,"key":"70:30","ar":"إِلَّا عَلَىٰٓ أَزْوَٰجِهِمْ أَوْ مَا مَلَكَتْ أَيْمَـٰنُهُمْ فَإِنَّهُمْ غَيْرُ مَلُومِينَ","en":"Except from their wives or those their right hands possess,1 for indeed, they are not to be blamed -","tr":"Illa AAala azwajihim awma malakat aymanuhum fa-innahum ghayru maloomeen","juz":29,"page":569},{"s":70,"a":31,"key":"70:31","ar":"فَمَنِ ٱبْتَغَىٰ وَرَآءَ ذَٰلِكَ فَأُو۟لَـٰٓئِكَ هُمُ ٱلْعَادُونَ","en":"But whoever seeks beyond that, then they are the transgressors -","tr":"Famani ibtagha waraa thalikafaola-ika humu alAAadoon","juz":29,"page":569},{"s":70,"a":32,"key":"70:32","ar":"وَٱلَّذِينَ هُمْ لِأَمَـٰنَـٰتِهِمْ وَعَهْدِهِمْ رَٰعُونَ","en":"And those who are to their trusts and promises attentive.","tr":"Wallatheena hum li-amanatihimwaAAahdihim raAAoon","juz":29,"page":569},{"s":70,"a":33,"key":"70:33","ar":"وَٱلَّذِينَ هُم بِشَهَـٰدَٰتِهِمْ قَآئِمُونَ","en":"And those who are in their testimonies upright","tr":"Wallatheena hum bishahadatihimqa-imoon","juz":29,"page":569},{"s":70,"a":34,"key":"70:34","ar":"وَٱلَّذِينَ هُمْ عَلَىٰ صَلَاتِهِمْ يُحَافِظُونَ","en":"And those who [carefully] maintain their prayer:","tr":"Wallatheena hum AAala salatihimyuhafithoon","juz":29,"page":569},{"s":70,"a":35,"key":"70:35","ar":"أُو۟لَـٰٓئِكَ فِى جَنَّـٰتٍ مُّكْرَمُونَ","en":"They will be in gardens,1 honored.","tr":"Ola-ika fee jannatin mukramoon","juz":29,"page":569},{"s":70,"a":36,"key":"70:36","ar":"فَمَالِ ٱلَّذِينَ كَفَرُوا۟ قِبَلَكَ مُهْطِعِينَ","en":"So what is [the matter] with those who disbelieve, hastening [from] before you, [O Muḥammad],","tr":"Famali allatheena kafarooqibalaka muhtiAAeen","juz":29,"page":569},{"s":70,"a":37,"key":"70:37","ar":"عَنِ ٱلْيَمِينِ وَعَنِ ٱلشِّمَالِ عِزِينَ","en":"[To sit] on [your] right and [your] left in separate groups?1","tr":"AAani alyameeni waAAani ashshimaliAAizeen","juz":29,"page":569},{"s":70,"a":38,"key":"70:38","ar":"أَيَطْمَعُ كُلُّ ٱمْرِئٍ مِّنْهُمْ أَن يُدْخَلَ جَنَّةَ نَعِيمٍ","en":"Does every person among them aspire to enter a garden of pleasure?","tr":"AyatmaAAu kullu imri-in minhum anyudkhala jannata naAAeem","juz":29,"page":569},{"s":70,"a":39,"key":"70:39","ar":"كَلَّآ ۖ إِنَّا خَلَقْنَـٰهُم مِّمَّا يَعْلَمُونَ","en":"No! Indeed, We have created them from that which they know.1","tr":"Kalla inna khalaqnahummimma yaAAlamoon","juz":29,"page":569},{"s":70,"a":40,"key":"70:40","ar":"فَلَآ أُقْسِمُ بِرَبِّ ٱلْمَشَـٰرِقِ وَٱلْمَغَـٰرِبِ إِنَّا لَقَـٰدِرُونَ","en":"So I swear by the Lord of [all] risings and settings1 that indeed We are able","tr":"Fala oqsimu birabbi almashariqiwalmagharibi inna laqadiroon","juz":29,"page":570},{"s":70,"a":41,"key":"70:41","ar":"عَلَىٰٓ أَن نُّبَدِّلَ خَيْرًا مِّنْهُمْ وَمَا نَحْنُ بِمَسْبُوقِينَ","en":"To replace them with better than them; and We are not to be outdone.","tr":"AAala an nubaddila khayran minhum wamanahnu bimasbooqeen","juz":29,"page":570},{"s":70,"a":42,"key":"70:42","ar":"فَذَرْهُمْ يَخُوضُوا۟ وَيَلْعَبُوا۟ حَتَّىٰ يُلَـٰقُوا۟ يَوْمَهُمُ ٱلَّذِى يُوعَدُونَ","en":"So leave them to converse vainly and amuse themselves until they meet their Day which they are promised -","tr":"Fatharhum yakhoodoowayalAAaboo hatta yulaqoo yawmahumu allatheeyooAAadoon","juz":29,"page":570},{"s":70,"a":43,"key":"70:43","ar":"يَوْمَ يَخْرُجُونَ مِنَ ٱلْأَجْدَاثِ سِرَاعًا كَأَنَّهُمْ إِلَىٰ نُصُبٍ يُوفِضُونَ","en":"The Day they will emerge from the graves rapidly as if they were, toward an erected idol, hastening.1","tr":"Yawma yakhrujoona mina al-ajdathi siraAAankaannahum ila nusubin yoofidoon","juz":29,"page":570},{"s":70,"a":44,"key":"70:44","ar":"خَـٰشِعَةً أَبْصَـٰرُهُمْ تَرْهَقُهُمْ ذِلَّةٌ ۚ ذَٰلِكَ ٱلْيَوْمُ ٱلَّذِى كَانُوا۟ يُوعَدُونَ","en":"Their eyes humbled, humiliation will cover them. That is the Day which they had been promised.","tr":"KhashiAAatan absaruhumtarhaquhum thillatun thalika alyawmu allatheekanoo yooAAadoon","juz":29,"page":570},{"s":71,"a":1,"key":"71:1","ar":" إِنَّآ أَرْسَلْنَا نُوحًا إِلَىٰ قَوْمِهِۦٓ أَنْ أَنذِرْ قَوْمَكَ مِن قَبْلِ أَن يَأْتِيَهُمْ عَذَابٌ أَلِيمٌ","en":"Indeed, We sent Noah to his people, [saying], \"Warn your people before there comes to them a painful punishment.\"","tr":"Inna arsalna noohan ilaqawmihi an anthir qawmaka min qabli an ya/tiyahum AAathabunaleem","juz":29,"page":570},{"s":71,"a":2,"key":"71:2","ar":"قَالَ يَـٰقَوْمِ إِنِّى لَكُمْ نَذِيرٌ مُّبِينٌ","en":"He said, \"O my people, indeed I am to you a clear warner -","tr":"Qala ya qawmi innee lakum natheerunmubeen","juz":29,"page":570},{"s":71,"a":3,"key":"71:3","ar":"أَنِ ٱعْبُدُوا۟ ٱللَّهَ وَٱتَّقُوهُ وَأَطِيعُونِ","en":"To worship Allāh, fear Him and obey me.","tr":"Ani oAAbudoo Allaha wattaqoohuwaateeAAoon","juz":29,"page":570},{"s":71,"a":4,"key":"71:4","ar":"يَغْفِرْ لَكُم مِّن ذُنُوبِكُمْ وَيُؤَخِّرْكُمْ إِلَىٰٓ أَجَلٍ مُّسَمًّى ۚ إِنَّ أَجَلَ ٱللَّهِ إِذَا جَآءَ لَا يُؤَخَّرُ ۖ لَوْ كُنتُمْ تَعْلَمُونَ","en":"He [i.e., Allāh] will forgive you of your sins and delay you for a specified term. Indeed, the time [set by] Allāh, when it comes, will not be delayed, if you only knew.\"","tr":"Yaghfir lakum min thunoobikumwayu-akhkhirkum ila ajalin musamman inna ajala Allahiitha jaa la yu-akhkharu law kuntumtaAAlamoon","juz":29,"page":570},{"s":71,"a":5,"key":"71:5","ar":"قَالَ رَبِّ إِنِّى دَعَوْتُ قَوْمِى لَيْلًا وَنَهَارًا","en":"He said, \"My Lord, indeed I invited my people [to truth] night and day.","tr":"Qala rabbi innee daAAawtu qawmeelaylan wanahara","juz":29,"page":570},{"s":71,"a":6,"key":"71:6","ar":"فَلَمْ يَزِدْهُمْ دُعَآءِىٓ إِلَّا فِرَارًا","en":"But my invitation increased them not except in flight [i.e., aversion].","tr":"Falam yazidhum duAAa-ee illafirara","juz":29,"page":570},{"s":71,"a":7,"key":"71:7","ar":"وَإِنِّى كُلَّمَا دَعَوْتُهُمْ لِتَغْفِرَ لَهُمْ جَعَلُوٓا۟ أَصَـٰبِعَهُمْ فِىٓ ءَاذَانِهِمْ وَٱسْتَغْشَوْا۟ ثِيَابَهُمْ وَأَصَرُّوا۟ وَٱسْتَكْبَرُوا۟ ٱسْتِكْبَارًا","en":"And indeed, every time I invited them that You may forgive them, they put their fingers in their ears, covered themselves with their garments,1 persisted, and were arrogant with [great] arrogance.","tr":"Wa-innee kullama daAAawtuhumlitaghfira lahum jaAAaloo asabiAAahum fee athanihimwastaghshaw thiyabahum waasarroo wastakbarooistikbara","juz":29,"page":570},{"s":71,"a":8,"key":"71:8","ar":"ثُمَّ إِنِّى دَعَوْتُهُمْ جِهَارًا","en":"Then I invited them publicly.","tr":"Thumma innee daAAawtuhum jihara","juz":29,"page":570},{"s":71,"a":9,"key":"71:9","ar":"ثُمَّ إِنِّىٓ أَعْلَنتُ لَهُمْ وَأَسْرَرْتُ لَهُمْ إِسْرَارًا","en":"Then I announced to them and [also] confided to them secretly","tr":"Thumma innee aAAlantu lahum waasrartu lahumisrara","juz":29,"page":570},{"s":71,"a":10,"key":"71:10","ar":"فَقُلْتُ ٱسْتَغْفِرُوا۟ رَبَّكُمْ إِنَّهُۥ كَانَ غَفَّارًا","en":"And said, 'Ask forgiveness of your Lord. Indeed, He is ever a Perpetual Forgiver.","tr":"Faqultu istaghfiroo rabbakum innahu kanaghaffara","juz":29,"page":570},{"s":71,"a":11,"key":"71:11","ar":"يُرْسِلِ ٱلسَّمَآءَ عَلَيْكُم مِّدْرَارًا","en":"He will send [rain from] the sky upon you in [continuing] showers","tr":"Yursili assamaa AAalaykummidrara","juz":29,"page":571},{"s":71,"a":12,"key":"71:12","ar":"وَيُمْدِدْكُم بِأَمْوَٰلٍ وَبَنِينَ وَيَجْعَل لَّكُمْ جَنَّـٰتٍ وَيَجْعَل لَّكُمْ أَنْهَـٰرًا","en":"And give you increase in wealth and children and provide for you gardens and provide for you rivers.","tr":"Wayumdidkum bi-amwalin wabaneenawayajAAal lakum jannatin wayajAAal lakum anhara","juz":29,"page":571},{"s":71,"a":13,"key":"71:13","ar":"مَّا لَكُمْ لَا تَرْجُونَ لِلَّهِ وَقَارًا","en":"What is [the matter] with you that you do not attribute to Allāh [due] grandeur","tr":"Ma lakum la tarjoona lillahiwaqara","juz":29,"page":571},{"s":71,"a":14,"key":"71:14","ar":"وَقَدْ خَلَقَكُمْ أَطْوَارًا","en":"While He has created you in stages?1","tr":"Waqad khalaqakum atwara","juz":29,"page":571},{"s":71,"a":15,"key":"71:15","ar":"أَلَمْ تَرَوْا۟ كَيْفَ خَلَقَ ٱللَّهُ سَبْعَ سَمَـٰوَٰتٍ طِبَاقًا","en":"Do you not consider how Allāh has created seven heavens in layers1","tr":"Alam taraw kayfa khalaqa AllahusabAAa samawatin tibaqa","juz":29,"page":571},{"s":71,"a":16,"key":"71:16","ar":"وَجَعَلَ ٱلْقَمَرَ فِيهِنَّ نُورًا وَجَعَلَ ٱلشَّمْسَ سِرَاجًا","en":"And made the moon therein a [reflected] light and made the sun a burning lamp?","tr":"WajaAAala alqamara feehinna nooran wajaAAalaashshamsa siraja","juz":29,"page":571},{"s":71,"a":17,"key":"71:17","ar":"وَٱللَّهُ أَنۢبَتَكُم مِّنَ ٱلْأَرْضِ نَبَاتًا","en":"And Allāh has caused you to grow from the earth a [progressive] growth.","tr":"Wallahu anbatakum mina al-ardinabata","juz":29,"page":571},{"s":71,"a":18,"key":"71:18","ar":"ثُمَّ يُعِيدُكُمْ فِيهَا وَيُخْرِجُكُمْ إِخْرَاجًا","en":"Then He will return you into it and extract you [another] extraction.","tr":"Thumma yuAAeedukum feehawayukhrijukum ikhraja","juz":29,"page":571},{"s":71,"a":19,"key":"71:19","ar":"وَٱللَّهُ جَعَلَ لَكُمُ ٱلْأَرْضَ بِسَاطًا","en":"And Allāh has made for you the earth an expanse","tr":"Wallahu jaAAala lakumu al-ardabisata","juz":29,"page":571},{"s":71,"a":20,"key":"71:20","ar":"لِّتَسْلُكُوا۟ مِنْهَا سُبُلًا فِجَاجًا","en":"That you may follow therein roads of passage.'\"","tr":"Litaslukoo minha subulan fijaja","juz":29,"page":571},{"s":71,"a":21,"key":"71:21","ar":"قَالَ نُوحٌ رَّبِّ إِنَّهُمْ عَصَوْنِى وَٱتَّبَعُوا۟ مَن لَّمْ يَزِدْهُ مَالُهُۥ وَوَلَدُهُۥٓ إِلَّا خَسَارًا","en":"Noah said, \"My Lord, indeed they have disobeyed me and followed him whose wealth and children will not increase him except in loss.","tr":"Qala noohun rabbi innahum AAasawneewattabaAAoo man lam yazidhu maluhu wawaladuhu illakhasara","juz":29,"page":571},{"s":71,"a":22,"key":"71:22","ar":"وَمَكَرُوا۟ مَكْرًا كُبَّارًا","en":"And they conspired an immense conspiracy","tr":"Wamakaroo makran kubbara","juz":29,"page":571},{"s":71,"a":23,"key":"71:23","ar":"وَقَالُوا۟ لَا تَذَرُنَّ ءَالِهَتَكُمْ وَلَا تَذَرُنَّ وَدًّا وَلَا سُوَاعًا وَلَا يَغُوثَ وَيَعُوقَ وَنَسْرًا","en":"And said, 'Never leave your gods and never leave Wadd or Suwāʿ or Yaghūth and Yaʿūq and Nasr.'1","tr":"Waqaloo la tatharunna alihatakumwala tatharunna waddan wala suwaAAanwala yaghootha wayaAAooqa wanasra","juz":29,"page":571},{"s":71,"a":24,"key":"71:24","ar":"وَقَدْ أَضَلُّوا۟ كَثِيرًا ۖ وَلَا تَزِدِ ٱلظَّـٰلِمِينَ إِلَّا ضَلَـٰلًا","en":"And already they have misled many. And, [my Lord], do not increase the wrongdoers except in error.\"","tr":"Waqad adalloo katheeran walatazidi aththalimeena illa dalala","juz":29,"page":571},{"s":71,"a":25,"key":"71:25","ar":"مِّمَّا خَطِيٓـَٔـٰتِهِمْ أُغْرِقُوا۟ فَأُدْخِلُوا۟ نَارًا فَلَمْ يَجِدُوا۟ لَهُم مِّن دُونِ ٱللَّهِ أَنصَارًا","en":"Because of their sins they were drowned and put into the Fire, and they found not for themselves besides Allāh [any] helpers.","tr":"Mimma khatee-atihimoghriqoo faodkhiloo naran falam yajidoo lahum min dooniAllahi ansara","juz":29,"page":571},{"s":71,"a":26,"key":"71:26","ar":"وَقَالَ نُوحٌ رَّبِّ لَا تَذَرْ عَلَى ٱلْأَرْضِ مِنَ ٱلْكَـٰفِرِينَ دَيَّارًا","en":"And Noah said, \"My Lord, do not leave upon the earth from among the disbelievers an inhabitant.","tr":"Waqala noohun rabbi latathar AAala al-ardi mina alkafireenadayyara","juz":29,"page":571},{"s":71,"a":27,"key":"71:27","ar":"إِنَّكَ إِن تَذَرْهُمْ يُضِلُّوا۟ عِبَادَكَ وَلَا يَلِدُوٓا۟ إِلَّا فَاجِرًا كَفَّارًا","en":"Indeed, if You leave them, they will mislead Your servants and not beget except [every] wicked one and [confirmed] disbeliever.","tr":"Innaka in tatharhum yudillooAAibadaka wala yalidoo illa fajirankaffara","juz":29,"page":571},{"s":71,"a":28,"key":"71:28","ar":"رَّبِّ ٱغْفِرْ لِى وَلِوَٰلِدَىَّ وَلِمَن دَخَلَ بَيْتِىَ مُؤْمِنًا وَلِلْمُؤْمِنِينَ وَٱلْمُؤْمِنَـٰتِ وَلَا تَزِدِ ٱلظَّـٰلِمِينَ إِلَّا تَبَارًۢا","en":"My Lord, forgive me and my parents and whoever enters my house a believer and the believing men and believing women. And do not increase the wrongdoers except in destruction.\"","tr":"Rabbi ighfir lee waliwalidayyawaliman dakhala baytiya mu/minan walilmu/mineena walmu/minatiwala tazidi aththalimeena illatabaran","juz":29,"page":571},{"s":72,"a":1,"key":"72:1","ar":" قُلْ أُوحِىَ إِلَىَّ أَنَّهُ ٱسْتَمَعَ نَفَرٌ مِّنَ ٱلْجِنِّ فَقَالُوٓا۟ إِنَّا سَمِعْنَا قُرْءَانًا عَجَبًا","en":"Say, [O Muḥammad], \"It has been revealed to me that a group of the jinn listened and said, 'Indeed, we have heard an amazing Qur’ān [i.e., recitation].","tr":"Qul oohiya ilayya annahu istamaAAanafarun mina aljinni faqaloo inna samiAAnaqur-anan AAajaba","juz":29,"page":572},{"s":72,"a":2,"key":"72:2","ar":"يَهْدِىٓ إِلَى ٱلرُّشْدِ فَـَٔامَنَّا بِهِۦ ۖ وَلَن نُّشْرِكَ بِرَبِّنَآ أَحَدًا","en":"It guides to the right course, and we have believed in it. And we will never associate with our Lord anyone.","tr":"Yahdee ila arrushdi faamannabihi walan nushrika birabbina ahada","juz":29,"page":572},{"s":72,"a":3,"key":"72:3","ar":"وَأَنَّهُۥ تَعَـٰلَىٰ جَدُّ رَبِّنَا مَا ٱتَّخَذَ صَـٰحِبَةً وَلَا وَلَدًا","en":"And [it teaches] that exalted is the nobleness of our Lord; He has not taken a wife or a son","tr":"Waannahu taAAala jaddu rabbinama ittakhatha sahibatan wala walada","juz":29,"page":572},{"s":72,"a":4,"key":"72:4","ar":"وَأَنَّهُۥ كَانَ يَقُولُ سَفِيهُنَا عَلَى ٱللَّهِ شَطَطًا","en":"And that our foolish one [i.e., Iblees]1 has been saying about Allāh an excessive transgression.","tr":"Waannahu kana yaqoolu safeehunaAAala Allahi shatata","juz":29,"page":572},{"s":72,"a":5,"key":"72:5","ar":"وَأَنَّا ظَنَنَّآ أَن لَّن تَقُولَ ٱلْإِنسُ وَٱلْجِنُّ عَلَى ٱللَّهِ كَذِبًا","en":"And we had thought that mankind and the jinn would never speak about Allāh a lie.","tr":"Waanna thanannaan lan taqoola al-insu waljinnu AAala Allahikathiba","juz":29,"page":572},{"s":72,"a":6,"key":"72:6","ar":"وَأَنَّهُۥ كَانَ رِجَالٌ مِّنَ ٱلْإِنسِ يَعُوذُونَ بِرِجَالٍ مِّنَ ٱلْجِنِّ فَزَادُوهُمْ رَهَقًا","en":"And there were men from mankind who sought refuge in men from the jinn, so they [only] increased them in burden [i.e., sin].","tr":"Waannahu kana rijalun minaal-insi yaAAoothoona birijalin mina aljinni fazadoohumrahaqa","juz":29,"page":572},{"s":72,"a":7,"key":"72:7","ar":"وَأَنَّهُمْ ظَنُّوا۟ كَمَا ظَنَنتُمْ أَن لَّن يَبْعَثَ ٱللَّهُ أَحَدًا","en":"And they had thought, as you thought, that Allāh would never send anyone [as a messenger].","tr":"Waannahum thannoo kama thanantuman lan yabAAatha Allahu ahada","juz":29,"page":572},{"s":72,"a":8,"key":"72:8","ar":"وَأَنَّا لَمَسْنَا ٱلسَّمَآءَ فَوَجَدْنَـٰهَا مُلِئَتْ حَرَسًا شَدِيدًا وَشُهُبًا","en":"And we have sought [to reach] the heaven but found it filled with powerful guards and burning flames.","tr":"Waanna lamasna assamaafawajadnaha muli-at harasan shadeedanwashuhuba","juz":29,"page":572},{"s":72,"a":9,"key":"72:9","ar":"وَأَنَّا كُنَّا نَقْعُدُ مِنْهَا مَقَـٰعِدَ لِلسَّمْعِ ۖ فَمَن يَسْتَمِعِ ٱلْـَٔانَ يَجِدْ لَهُۥ شِهَابًا رَّصَدًا","en":"And we used to sit therein in positions for hearing,1 but whoever listens now will find a burning flame lying in wait for him.","tr":"Waanna kunna naqAAudu minhamaqaAAida lissamAAi faman yastamiAAi al-anayajid lahu shihaban rasada","juz":29,"page":572},{"s":72,"a":10,"key":"72:10","ar":"وَأَنَّا لَا نَدْرِىٓ أَشَرٌّ أُرِيدَ بِمَن فِى ٱلْأَرْضِ أَمْ أَرَادَ بِهِمْ رَبُّهُمْ رَشَدًا","en":"And we do not know [therefore] whether evil is intended for those on earth or whether their Lord intends for them a right course.","tr":"Waanna la nadree asharrunoreeda biman fee al-ardi am arada bihim rabbuhumrashada","juz":29,"page":572},{"s":72,"a":11,"key":"72:11","ar":"وَأَنَّا مِنَّا ٱلصَّـٰلِحُونَ وَمِنَّا دُونَ ذَٰلِكَ ۖ كُنَّا طَرَآئِقَ قِدَدًا","en":"And among us are the righteous, and among us are [others] not so; we were [of] divided ways.1","tr":"Waanna minna assalihoonawaminna doona thalika kunna tara-iqaqidada","juz":29,"page":572},{"s":72,"a":12,"key":"72:12","ar":"وَأَنَّا ظَنَنَّآ أَن لَّن نُّعْجِزَ ٱللَّهَ فِى ٱلْأَرْضِ وَلَن نُّعْجِزَهُۥ هَرَبًا","en":"And we have become certain that we will never cause failure to Allāh upon earth, nor can we escape Him by flight.","tr":"Wanna thanannaan lan nuAAjiza Allaha fee al-ardi walan nuAAjizahuharaba","juz":29,"page":572},{"s":72,"a":13,"key":"72:13","ar":"وَأَنَّا لَمَّا سَمِعْنَا ٱلْهُدَىٰٓ ءَامَنَّا بِهِۦ ۖ فَمَن يُؤْمِنۢ بِرَبِّهِۦ فَلَا يَخَافُ بَخْسًا وَلَا رَهَقًا","en":"And when we heard the guidance [i.e., the Qur’ān], we believed in it. And whoever believes in his Lord will not fear deprivation or burden.1","tr":"Waanna lamma samiAAnaalhuda amanna bihi faman yu/min birabbihifala yakhafu bakhsan wala rahaqa","juz":29,"page":572},{"s":72,"a":14,"key":"72:14","ar":"وَأَنَّا مِنَّا ٱلْمُسْلِمُونَ وَمِنَّا ٱلْقَـٰسِطُونَ ۖ فَمَنْ أَسْلَمَ فَأُو۟لَـٰٓئِكَ تَحَرَّوْا۟ رَشَدًا","en":"And among us are Muslims [in submission to Allāh], and among us are the unjust.1 And whoever has become Muslim - those have sought out the right course.","tr":"Waanna minna almuslimoonawaminna alqasitoona faman aslama faola-ikataharraw rashada","juz":29,"page":573},{"s":72,"a":15,"key":"72:15","ar":"وَأَمَّا ٱلْقَـٰسِطُونَ فَكَانُوا۟ لِجَهَنَّمَ حَطَبًا","en":"But as for the unjust, they will be, for Hell, firewood.'","tr":"Waama alqasitoona fakanoolijahannama hataba","juz":29,"page":573},{"s":72,"a":16,"key":"72:16","ar":"وَأَلَّوِ ٱسْتَقَـٰمُوا۟ عَلَى ٱلطَّرِيقَةِ لَأَسْقَيْنَـٰهُم مَّآءً غَدَقًا","en":"And [Allāh revealed] that if they had remained straight on the way, We would have given them abundant rain [i.e., provision].","tr":"Waallawi istaqamoo AAala attareeqatilaasqaynahum maan ghadaqa","juz":29,"page":573},{"s":72,"a":17,"key":"72:17","ar":"لِّنَفْتِنَهُمْ فِيهِ ۚ وَمَن يُعْرِضْ عَن ذِكْرِ رَبِّهِۦ يَسْلُكْهُ عَذَابًا صَعَدًا","en":"So We might test them therein. And whoever turns away from the remembrance of his Lord1 He will put into arduous punishment.","tr":"Linaftinahum feehi waman yuAArid AAanthikri rabbihi yasluk-hu AAathaban saAAada","juz":29,"page":573},{"s":72,"a":18,"key":"72:18","ar":"وَأَنَّ ٱلْمَسَـٰجِدَ لِلَّهِ فَلَا تَدْعُوا۟ مَعَ ٱللَّهِ أَحَدًا","en":"And [He revealed] that the masjids1 are for Allāh, so do not invoke2 with Allāh anyone.","tr":"Waanna almasajida lillahi falatadAAoo maAAa Allahi ahada","juz":29,"page":573},{"s":72,"a":19,"key":"72:19","ar":"وَأَنَّهُۥ لَمَّا قَامَ عَبْدُ ٱللَّهِ يَدْعُوهُ كَادُوا۟ يَكُونُونَ عَلَيْهِ لِبَدًا","en":"And that when the Servant [i.e., Prophet] of Allāh stood up supplicating Him, they almost became about him a compacted mass.\"1","tr":"Waannahu lamma qama AAabdu AllahiyadAAoohu kadoo yakoonoona AAalayhi libada","juz":29,"page":573},{"s":72,"a":20,"key":"72:20","ar":"قُلْ إِنَّمَآ أَدْعُوا۟ رَبِّى وَلَآ أُشْرِكُ بِهِۦٓ أَحَدًا","en":"Say, [O Muḥammad], \"I only invoke my Lord and do not associate with Him anyone.\"","tr":"Qul innama adAAoo rabbee walaoshriku bihi ahada","juz":29,"page":573},{"s":72,"a":21,"key":"72:21","ar":"قُلْ إِنِّى لَآ أَمْلِكُ لَكُمْ ضَرًّا وَلَا رَشَدًا","en":"Say, \"Indeed, I do not possess for you [the power of] harm or right direction.\"","tr":"Qul innee la amliku lakum darranwala rashada","juz":29,"page":573},{"s":72,"a":22,"key":"72:22","ar":"قُلْ إِنِّى لَن يُجِيرَنِى مِنَ ٱللَّهِ أَحَدٌ وَلَنْ أَجِدَ مِن دُونِهِۦ مُلْتَحَدًا","en":"Say, \"Indeed, there will never protect me from Allāh anyone [if I should disobey], nor will I find in other than Him a refuge.","tr":"Qul innee lan yujeeranee mina Allahiahadun walan ajida min doonihi multahada","juz":29,"page":573},{"s":72,"a":23,"key":"72:23","ar":"إِلَّا بَلَـٰغًا مِّنَ ٱللَّهِ وَرِسَـٰلَـٰتِهِۦ ۚ وَمَن يَعْصِ ٱللَّهَ وَرَسُولَهُۥ فَإِنَّ لَهُۥ نَارَ جَهَنَّمَ خَـٰلِدِينَ فِيهَآ أَبَدًا","en":"But [I have for you] only notification from Allāh, and His messages.\" And whoever disobeys Allāh and His Messenger - then indeed, for him is the fire of Hell; they will abide therein forever.","tr":"Illa balaghan mina Allahiwarisalatihi waman yaAAsi Allahawarasoolahu fa-inna lahu nara jahannama khalideenafeeha abada","juz":29,"page":573},{"s":72,"a":24,"key":"72:24","ar":"حَتَّىٰٓ إِذَا رَأَوْا۟ مَا يُوعَدُونَ فَسَيَعْلَمُونَ مَنْ أَضْعَفُ نَاصِرًا وَأَقَلُّ عَدَدًا","en":"[The disbelievers continue] until, when they see that which they are promised, then they will know who is weaker in helpers and less in number.","tr":"Hatta itha raaw mayooAAadoona fasayaAAlamoona man adAAafu nasiranwaaqallu AAadada","juz":29,"page":573},{"s":72,"a":25,"key":"72:25","ar":"قُلْ إِنْ أَدْرِىٓ أَقَرِيبٌ مَّا تُوعَدُونَ أَمْ يَجْعَلُ لَهُۥ رَبِّىٓ أَمَدًا","en":"Say, \"I do not know if what you are promised is near or if my Lord will grant for it a [long] period.\"","tr":"Qul in adree aqareebun ma tooAAadoonaam yajAAalu lahu rabbee amada","juz":29,"page":573},{"s":72,"a":26,"key":"72:26","ar":"عَـٰلِمُ ٱلْغَيْبِ فَلَا يُظْهِرُ عَلَىٰ غَيْبِهِۦٓ أَحَدًا","en":"[He is] Knower of the unseen, and He does not disclose His [knowledge of the] unseen to anyone","tr":"AAalimu alghaybi fala yuthhiruAAala ghaybihi ahada","juz":29,"page":573},{"s":72,"a":27,"key":"72:27","ar":"إِلَّا مَنِ ٱرْتَضَىٰ مِن رَّسُولٍ فَإِنَّهُۥ يَسْلُكُ مِنۢ بَيْنِ يَدَيْهِ وَمِنْ خَلْفِهِۦ رَصَدًا","en":"Except whom He has approved of messengers, and indeed, He sends before him [i.e., each messenger] and behind him observers1","tr":"Illa mani irtada min rasoolinfa-innahu yasluku min bayni yadayhi wamin khalfihi rasada","juz":29,"page":573},{"s":72,"a":28,"key":"72:28","ar":"لِّيَعْلَمَ أَن قَدْ أَبْلَغُوا۟ رِسَـٰلَـٰتِ رَبِّهِمْ وَأَحَاطَ بِمَا لَدَيْهِمْ وَأَحْصَىٰ كُلَّ شَىْءٍ عَدَدًۢا","en":"That he [i.e., Muḥammad (ﷺ)] may know1 that they have conveyed the messages of their Lord; and He has encompassed whatever is with them and has enumerated all things in number.","tr":"LiyaAAlama an qad ablaghoo risalatirabbihim waahata bima ladayhim waahsa kullashay-in AAadada","juz":29,"page":573},{"s":73,"a":1,"key":"73:1","ar":" يَـٰٓأَيُّهَا ٱلْمُزَّمِّلُ","en":"O you who wraps himself [in clothing]1","tr":"Ya ayyuha almuzzammil","juz":29,"page":574},{"s":73,"a":2,"key":"73:2","ar":"قُمِ ٱلَّيْلَ إِلَّا قَلِيلًا","en":"Arise [to pray] the night, except for a little -","tr":"Qumi allayla illa qaleela","juz":29,"page":574},{"s":73,"a":3,"key":"73:3","ar":"نِّصْفَهُۥٓ أَوِ ٱنقُصْ مِنْهُ قَلِيلًا","en":"Half of it - or subtract from it a little","tr":"Nisfahu awi onqus minhu qaleela","juz":29,"page":574},{"s":73,"a":4,"key":"73:4","ar":"أَوْ زِدْ عَلَيْهِ وَرَتِّلِ ٱلْقُرْءَانَ تَرْتِيلًا","en":"Or add to it, and recite the Qur’ān with measured recitation.","tr":"Aw zid AAalayhi warattili alqur-anatarteela","juz":29,"page":574},{"s":73,"a":5,"key":"73:5","ar":"إِنَّا سَنُلْقِى عَلَيْكَ قَوْلًا ثَقِيلًا","en":"Indeed, We will cast upon you a heavy word.1","tr":"Inna sanulqee AAalayka qawlan thaqeela","juz":29,"page":574},{"s":73,"a":6,"key":"73:6","ar":"إِنَّ نَاشِئَةَ ٱلَّيْلِ هِىَ أَشَدُّ وَطْـًٔا وَأَقْوَمُ قِيلًا","en":"Indeed, the hours of the night are more effective for concurrence [of heart and tongue]1 and more suitable for words.2","tr":"Inna nashi-ata allayli hiya ashaddu wat-anwaaqwamu qeela","juz":29,"page":574},{"s":73,"a":7,"key":"73:7","ar":"إِنَّ لَكَ فِى ٱلنَّهَارِ سَبْحًا طَوِيلًا","en":"Indeed, for you by day is prolonged occupation.","tr":"Inna laka fee annahari sabhantaweela","juz":29,"page":574},{"s":73,"a":8,"key":"73:8","ar":"وَٱذْكُرِ ٱسْمَ رَبِّكَ وَتَبَتَّلْ إِلَيْهِ تَبْتِيلًا","en":"And remember the name of your Lord and devote yourself to Him with [complete] devotion.","tr":"Wathkuri isma rabbikawatabattal ilayhi tabteela","juz":29,"page":574},{"s":73,"a":9,"key":"73:9","ar":"رَّبُّ ٱلْمَشْرِقِ وَٱلْمَغْرِبِ لَآ إِلَـٰهَ إِلَّا هُوَ فَٱتَّخِذْهُ وَكِيلًا","en":"[He is] the Lord of the East and the West; there is no deity except Him, so take Him as Disposer of [your] affairs.1","tr":"Rabbu almashriqi walmaghribi lailaha illa huwa fattakhithhu wakeela","juz":29,"page":574},{"s":73,"a":10,"key":"73:10","ar":"وَٱصْبِرْ عَلَىٰ مَا يَقُولُونَ وَٱهْجُرْهُمْ هَجْرًا جَمِيلًا","en":"And be patient over what they say and avoid them with gracious avoidance.","tr":"Wasbir AAala mayaqooloona wahjurhum hajran jameela","juz":29,"page":574},{"s":73,"a":11,"key":"73:11","ar":"وَذَرْنِى وَٱلْمُكَذِّبِينَ أُو۟لِى ٱلنَّعْمَةِ وَمَهِّلْهُمْ قَلِيلًا","en":"And leave Me with [the matter of] the deniers, those of ease [in life], and allow them respite a little.","tr":"Watharnee walmukaththibeenaolee annaAAmati wamahhilhum qaleela","juz":29,"page":574},{"s":73,"a":12,"key":"73:12","ar":"إِنَّ لَدَيْنَآ أَنكَالًا وَجَحِيمًا","en":"Indeed, with Us [for them] are shackles and burning fire.","tr":"Inna ladayna ankalan wajaheema","juz":29,"page":574},{"s":73,"a":13,"key":"73:13","ar":"وَطَعَامًا ذَا غُصَّةٍ وَعَذَابًا أَلِيمًا","en":"And food that chokes and a painful punishment -","tr":"WataAAaman tha ghussatinwaAAathaban aleema","juz":29,"page":574},{"s":73,"a":14,"key":"73:14","ar":"يَوْمَ تَرْجُفُ ٱلْأَرْضُ وَٱلْجِبَالُ وَكَانَتِ ٱلْجِبَالُ كَثِيبًا مَّهِيلًا","en":"On the Day the earth and the mountains will convulse and the mountains will become a heap of sand pouring down.","tr":"Yawma tarjufu al-ardu waljibaluwakanati aljibalu katheeban maheela","juz":29,"page":574},{"s":73,"a":15,"key":"73:15","ar":"إِنَّآ أَرْسَلْنَآ إِلَيْكُمْ رَسُولًا شَـٰهِدًا عَلَيْكُمْ كَمَآ أَرْسَلْنَآ إِلَىٰ فِرْعَوْنَ رَسُولًا","en":"Indeed, We have sent to you a Messenger as a witness upon you just as We sent to Pharaoh a messenger.","tr":"Inna arsalna ilaykum rasoolanshahidan AAalaykum kama arsalna ilafirAAawna rasoola","juz":29,"page":574},{"s":73,"a":16,"key":"73:16","ar":"فَعَصَىٰ فِرْعَوْنُ ٱلرَّسُولَ فَأَخَذْنَـٰهُ أَخْذًا وَبِيلًا","en":"But Pharaoh disobeyed the messenger, so We seized him with a ruinous seizure.","tr":"FaAAasa firAAawnu arrasoolafaakhathnahu akhthan wabeela","juz":29,"page":574},{"s":73,"a":17,"key":"73:17","ar":"فَكَيْفَ تَتَّقُونَ إِن كَفَرْتُمْ يَوْمًا يَجْعَلُ ٱلْوِلْدَٰنَ شِيبًا","en":"Then how can you fear, if you disbelieve, a Day that will make the children white-haired?1","tr":"Fakayfa tattaqoona in kafartum yawmanyajAAalu alwildana sheeba","juz":29,"page":574},{"s":73,"a":18,"key":"73:18","ar":"ٱلسَّمَآءُ مُنفَطِرٌۢ بِهِۦ ۚ كَانَ وَعْدُهُۥ مَفْعُولًا","en":"The heaven will break apart therefrom;1 ever is His promise fulfilled.","tr":"Assamao munfatirunbihi kana waAAduhu mafAAoola","juz":29,"page":574},{"s":73,"a":19,"key":"73:19","ar":"إِنَّ هَـٰذِهِۦ تَذْكِرَةٌ ۖ فَمَن شَآءَ ٱتَّخَذَ إِلَىٰ رَبِّهِۦ سَبِيلًا","en":"Indeed, this is a reminder, so whoever wills may take to his Lord a way.","tr":"Inna hathihi tathkiratun famanshaa ittakhatha ila rabbihi sabeela","juz":29,"page":574},{"s":73,"a":20,"key":"73:20","ar":"۞ إِنَّ رَبَّكَ يَعْلَمُ أَنَّكَ تَقُومُ أَدْنَىٰ مِن ثُلُثَىِ ٱلَّيْلِ وَنِصْفَهُۥ وَثُلُثَهُۥ وَطَآئِفَةٌ مِّنَ ٱلَّذِينَ مَعَكَ ۚ وَٱللَّهُ يُقَدِّرُ ٱلَّيْلَ وَٱلنَّهَارَ ۚ عَلِمَ أَن لَّن تُحْصُوهُ فَتَابَ عَلَيْكُمْ ۖ فَٱقْرَءُوا۟ مَا تَيَسَّرَ مِنَ ٱلْقُرْءَانِ ۚ عَلِمَ أَن سَيَكُونُ مِنكُم مَّرْضَىٰ ۙ وَءَاخَرُونَ يَضْرِبُونَ فِى ٱلْأَرْضِ يَبْتَغُونَ مِن فَضْلِ ٱللَّهِ ۙ وَءَاخَرُونَ يُقَـٰتِلُونَ فِى سَبِيلِ ٱللَّهِ ۖ فَٱقْرَءُوا۟ مَا تَيَسَّرَ مِنْهُ ۚ وَأَقِيمُوا۟ ٱلصَّلَوٰةَ وَءَاتُوا۟ ٱلزَّكَوٰةَ وَأَقْرِضُوا۟ ٱللَّهَ قَرْضًا حَسَنًا ۚ وَمَا تُقَدِّمُوا۟ لِأَنفُسِكُم مِّنْ خَيْرٍ تَجِدُوهُ عِندَ ٱللَّهِ هُوَ خَيْرًا وَأَعْظَمَ أَجْرًا ۚ وَٱسْتَغْفِرُوا۟ ٱللَّهَ ۖ إِنَّ ٱللَّهَ غَفُورٌ رَّحِيمٌۢ","en":"Indeed, your Lord knows, [O Muḥammad], that you stand [in prayer] almost two thirds of the night or half of it or a third of it, and [so do] a group of those with you. And Allāh determines [the extent of] the night and the day. He has known that you [Muslims] will not be able to do it1 and has turned to you in forgiveness, so recite what is easy [for you] of the Qur’ān. He has known that there will be among you those who are ill and others traveling throughout the land seeking [something] of the bounty of Allāh and others fighting for the cause of Allāh. So recite what is easy from it and establish prayer and give zakāh and loan Allāh a goodly loan.2 And whatever good you put forward for yourselves - you will find it with Allāh. It is better and greater in reward. And seek forgiveness of Allāh. Indeed, Allāh is Forgiving and Merciful.","tr":"Inna rabbaka yaAAlamu annaka taqoomu adnamin thuluthayi allayli wanisfahu wathuluthahu wata-ifatunmina allatheena maAAaka wallahu yuqaddiruallayla wannahara AAalima an lan tuhsoohufataba AAalaykum faqraoo ma tayassara minaalqur-ani AAalima an sayakoonu minkum marda waakharoonayadriboona fee al-ardi yabtaghoona min fadliAllahi waakharoona yuqatiloona fee sabeeliAllahi faqraoo ma tayassara minhu waaqeemooassalata waatoo azzakatawaaqridoo Allaha qardan hasanan wamatuqaddimoo li-anfusikum min khayrin tajidoohu AAinda Allahihuwa khayran waaAAthama ajran wastaghfirooAllaha inna Allaha ghafoorun raheem","juz":29,"page":575},{"s":74,"a":1,"key":"74:1","ar":" يَـٰٓأَيُّهَا ٱلْمُدَّثِّرُ","en":"O you who covers himself [with a garment],1","tr":"Ya ayyuha almuddaththir","juz":29,"page":575},{"s":74,"a":2,"key":"74:2","ar":"قُمْ فَأَنذِرْ","en":"Arise and warn.","tr":"Qum faanthir","juz":29,"page":575},{"s":74,"a":3,"key":"74:3","ar":"وَرَبَّكَ فَكَبِّرْ","en":"And your Lord glorify.","tr":"Warabbaka fakabbir","juz":29,"page":575},{"s":74,"a":4,"key":"74:4","ar":"وَثِيَابَكَ فَطَهِّرْ","en":"And your clothing purify.","tr":"Wathiyabaka fatahhir","juz":29,"page":575},{"s":74,"a":5,"key":"74:5","ar":"وَٱلرُّجْزَ فَٱهْجُرْ","en":"And uncleanliness1 avoid.","tr":"Warrujza fahjur","juz":29,"page":575},{"s":74,"a":6,"key":"74:6","ar":"وَلَا تَمْنُن تَسْتَكْثِرُ","en":"And do not confer favor to acquire more1.","tr":"Wala tamnun tastakthir","juz":29,"page":575},{"s":74,"a":7,"key":"74:7","ar":"وَلِرَبِّكَ فَٱصْبِرْ","en":"But for your Lord be patient.","tr":"Walirabbika fasbir","juz":29,"page":575},{"s":74,"a":8,"key":"74:8","ar":"فَإِذَا نُقِرَ فِى ٱلنَّاقُورِ","en":"And when the trumpet is blown,","tr":"Fa-itha nuqira fee annaqoor","juz":29,"page":575},{"s":74,"a":9,"key":"74:9","ar":"فَذَٰلِكَ يَوْمَئِذٍ يَوْمٌ عَسِيرٌ","en":"That Day will be a difficult day","tr":"Fathalika yawma-ithin yawmunAAaseer","juz":29,"page":575},{"s":74,"a":10,"key":"74:10","ar":"عَلَى ٱلْكَـٰفِرِينَ غَيْرُ يَسِيرٍ","en":"For the disbelievers - not easy.","tr":"AAala alkafireena ghayruyaseer","juz":29,"page":575},{"s":74,"a":11,"key":"74:11","ar":"ذَرْنِى وَمَنْ خَلَقْتُ وَحِيدًا","en":"Leave Me with the one I created alone1","tr":"Tharnee waman khalaqtu waheeda","juz":29,"page":575},{"s":74,"a":12,"key":"74:12","ar":"وَجَعَلْتُ لَهُۥ مَالًا مَّمْدُودًا","en":"And to whom I granted extensive wealth","tr":"WajaAAaltu lahu malan mamdooda","juz":29,"page":575},{"s":74,"a":13,"key":"74:13","ar":"وَبَنِينَ شُهُودًا","en":"And children present [with him]","tr":"Wabaneena shuhooda","juz":29,"page":575},{"s":74,"a":14,"key":"74:14","ar":"وَمَهَّدتُّ لَهُۥ تَمْهِيدًا","en":"And spread [everything] before him, easing [his life].","tr":"Wamahhadtu lahu tamheeda","juz":29,"page":575},{"s":74,"a":15,"key":"74:15","ar":"ثُمَّ يَطْمَعُ أَنْ أَزِيدَ","en":"Then he desires that I should add more.","tr":"Thumma yatmaAAu an azeed","juz":29,"page":575},{"s":74,"a":16,"key":"74:16","ar":"كَلَّآ ۖ إِنَّهُۥ كَانَ لِـَٔايَـٰتِنَا عَنِيدًا","en":"No! Indeed, he has been toward Our verses obstinate.","tr":"Kalla innahu kana li-ayatinaAAaneeda","juz":29,"page":575},{"s":74,"a":17,"key":"74:17","ar":"سَأُرْهِقُهُۥ صَعُودًا","en":"I will cover him with arduous torment.","tr":"Saorhiquhu saAAooda","juz":29,"page":575},{"s":74,"a":18,"key":"74:18","ar":"إِنَّهُۥ فَكَّرَ وَقَدَّرَ","en":"Indeed, he thought and deliberated.1","tr":"Innahu fakkara waqaddar","juz":29,"page":576},{"s":74,"a":19,"key":"74:19","ar":"فَقُتِلَ كَيْفَ قَدَّرَ","en":"So may he be destroyed [for] how he deliberated.","tr":"Faqutila kayfa qaddar","juz":29,"page":576},{"s":74,"a":20,"key":"74:20","ar":"ثُمَّ قُتِلَ كَيْفَ قَدَّرَ","en":"Then may he be destroyed [for] how he deliberated.","tr":"Thumma qutila kayfa qaddar","juz":29,"page":576},{"s":74,"a":21,"key":"74:21","ar":"ثُمَّ نَظَرَ","en":"Then he considered [again];","tr":"Thumma nathar","juz":29,"page":576},{"s":74,"a":22,"key":"74:22","ar":"ثُمَّ عَبَسَ وَبَسَرَ","en":"Then he frowned and scowled;","tr":"Thumma AAabasa wabasar","juz":29,"page":576},{"s":74,"a":23,"key":"74:23","ar":"ثُمَّ أَدْبَرَ وَٱسْتَكْبَرَ","en":"Then he turned back and was arrogant","tr":"Thumma adbara wastakbar","juz":29,"page":576},{"s":74,"a":24,"key":"74:24","ar":"فَقَالَ إِنْ هَـٰذَآ إِلَّا سِحْرٌ يُؤْثَرُ","en":"And said, \"This is not but magic imitated [from others].","tr":"Faqala in hatha illa sihrunyu/thar","juz":29,"page":576},{"s":74,"a":25,"key":"74:25","ar":"إِنْ هَـٰذَآ إِلَّا قَوْلُ ٱلْبَشَرِ","en":"This is not but the word of a human being.\"","tr":"In hatha illa qawlu albashar","juz":29,"page":576},{"s":74,"a":26,"key":"74:26","ar":"سَأُصْلِيهِ سَقَرَ","en":"I will drive him into Saqar.1","tr":"Saosleehi saqar","juz":29,"page":576},{"s":74,"a":27,"key":"74:27","ar":"وَمَآ أَدْرَىٰكَ مَا سَقَرُ","en":"And what can make you know what is Saqar?","tr":"Wama adraka ma saqar","juz":29,"page":576},{"s":74,"a":28,"key":"74:28","ar":"لَا تُبْقِى وَلَا تَذَرُ","en":"It lets nothing remain and leaves nothing [unburned],","tr":"La tubqee wala tathar","juz":29,"page":576},{"s":74,"a":29,"key":"74:29","ar":"لَوَّاحَةٌ لِّلْبَشَرِ","en":"Altering [i.e., blackening] the skins.","tr":"Lawwahatun lilbashar","juz":29,"page":576},{"s":74,"a":30,"key":"74:30","ar":"عَلَيْهَا تِسْعَةَ عَشَرَ","en":"Over it are nineteen [angels].","tr":"AAalayha tisAAata AAashar","juz":29,"page":576},{"s":74,"a":31,"key":"74:31","ar":"وَمَا جَعَلْنَآ أَصْحَـٰبَ ٱلنَّارِ إِلَّا مَلَـٰٓئِكَةً ۙ وَمَا جَعَلْنَا عِدَّتَهُمْ إِلَّا فِتْنَةً لِّلَّذِينَ كَفَرُوا۟ لِيَسْتَيْقِنَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ وَيَزْدَادَ ٱلَّذِينَ ءَامَنُوٓا۟ إِيمَـٰنًا ۙ وَلَا يَرْتَابَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ وَٱلْمُؤْمِنُونَ ۙ وَلِيَقُولَ ٱلَّذِينَ فِى قُلُوبِهِم مَّرَضٌ وَٱلْكَـٰفِرُونَ مَاذَآ أَرَادَ ٱللَّهُ بِهَـٰذَا مَثَلًا ۚ كَذَٰلِكَ يُضِلُّ ٱللَّهُ مَن يَشَآءُ وَيَهْدِى مَن يَشَآءُ ۚ وَمَا يَعْلَمُ جُنُودَ رَبِّكَ إِلَّا هُوَ ۚ وَمَا هِىَ إِلَّا ذِكْرَىٰ لِلْبَشَرِ","en":"And We have not made the keepers of the Fire except angels. And We have not made their number except as a trial for those who disbelieve - that those who were given the Scripture will be convinced and those who have believed will increase in faith and those who were given the Scripture and the believers will not doubt and that those in whose hearts is disease [i.e., hypocrisy] and the disbelievers will say, \"What does Allāh intend by this as an example?\" Thus does Allāh send astray whom He wills and guide whom He wills. And none knows the soldiers of your Lord except Him. And it [i.e., mention of the Fire] is not but a reminder to humanity.","tr":"Wama jaAAalna as-habaannari illa mala-ikatan wamajaAAalna AAiddatahum illa fitnatan lillatheenakafaroo liyastayqina allatheena ootoo alkitabawayazdada allatheena amanoo eemananwala yartaba allatheena ootoo alkitabawalmu/minoona waliyaqoola allatheena feequloobihim maradun walkafiroona mathaarada Allahu bihatha mathalan kathalikayudillu Allahu man yashao wayahdee man yashaowama yaAAlamu junooda rabbika illa huwa wamahiya illa thikra lilbashar","juz":29,"page":576},{"s":74,"a":32,"key":"74:32","ar":"كَلَّا وَٱلْقَمَرِ","en":"No! By the moon.","tr":"Kalla walqamar","juz":29,"page":576},{"s":74,"a":33,"key":"74:33","ar":"وَٱلَّيْلِ إِذْ أَدْبَرَ","en":"And [by] the night when it departs.","tr":"Wallayli ith adbar","juz":29,"page":576},{"s":74,"a":34,"key":"74:34","ar":"وَٱلصُّبْحِ إِذَآ أَسْفَرَ","en":"And [by] the morning when it brightens,","tr":"Wassubhi ithaasfar","juz":29,"page":576},{"s":74,"a":35,"key":"74:35","ar":"إِنَّهَا لَإِحْدَى ٱلْكُبَرِ","en":"Indeed, it [i.e., the Fire] is of the greatest [afflictions].","tr":"Innaha la-ihda alkubar","juz":29,"page":576},{"s":74,"a":36,"key":"74:36","ar":"نَذِيرًا لِّلْبَشَرِ","en":"As a warning to humanity -","tr":"Natheeran lilbashar","juz":29,"page":576},{"s":74,"a":37,"key":"74:37","ar":"لِمَن شَآءَ مِنكُمْ أَن يَتَقَدَّمَ أَوْ يَتَأَخَّرَ","en":"To whoever wills among you to proceed1 or stay behind.","tr":"Liman shaa minkum an yataqaddama awyataakhkhar","juz":29,"page":576},{"s":74,"a":38,"key":"74:38","ar":"كُلُّ نَفْسٍۭ بِمَا كَسَبَتْ رَهِينَةٌ","en":"Every soul, for what it has earned, will be retained1.","tr":"Kullu nafsin bima kasabat raheena","juz":29,"page":576},{"s":74,"a":39,"key":"74:39","ar":"إِلَّآ أَصْحَـٰبَ ٱلْيَمِينِ","en":"Except the companions of the right,1.","tr":"Illa as-haba alyameen","juz":29,"page":576},{"s":74,"a":40,"key":"74:40","ar":"فِى جَنَّـٰتٍ يَتَسَآءَلُونَ","en":"[Who will be] in gardens, questioning each other","tr":"Fee jannatin yatasaaloon","juz":29,"page":576},{"s":74,"a":41,"key":"74:41","ar":"عَنِ ٱلْمُجْرِمِينَ","en":"About the criminals,","tr":"AAani almujrimeen","juz":29,"page":576},{"s":74,"a":42,"key":"74:42","ar":"مَا سَلَكَكُمْ فِى سَقَرَ","en":"[And asking them], \"What put you into Saqar?\"","tr":"Ma salakakum fee saqar","juz":29,"page":576},{"s":74,"a":43,"key":"74:43","ar":"قَالُوا۟ لَمْ نَكُ مِنَ ٱلْمُصَلِّينَ","en":"They will say, \"We were not of those who prayed,","tr":"Qaloo lam naku mina almusalleen","juz":29,"page":576},{"s":74,"a":44,"key":"74:44","ar":"وَلَمْ نَكُ نُطْعِمُ ٱلْمِسْكِينَ","en":"Nor did we used to feed the poor.","tr":"Walam naku nutAAimu almiskeen","juz":29,"page":576},{"s":74,"a":45,"key":"74:45","ar":"وَكُنَّا نَخُوضُ مَعَ ٱلْخَآئِضِينَ","en":"And we used to enter into vain discourse with those who engaged [in it],","tr":"Wakunna nakhoodu maAAa alkha-ideen","juz":29,"page":576},{"s":74,"a":46,"key":"74:46","ar":"وَكُنَّا نُكَذِّبُ بِيَوْمِ ٱلدِّينِ","en":"And we used to deny the Day of Recompense","tr":"Wakunna nukaththibu biyawmi addeen","juz":29,"page":576},{"s":74,"a":47,"key":"74:47","ar":"حَتَّىٰٓ أَتَىٰنَا ٱلْيَقِينُ","en":"Until there came to us the certainty [i.e., death].\"","tr":"Hatta atanaalyaqeen","juz":29,"page":576},{"s":74,"a":48,"key":"74:48","ar":"فَمَا تَنفَعُهُمْ شَفَـٰعَةُ ٱلشَّـٰفِعِينَ","en":"So there will not benefit them the intercession of [any] intercessors.","tr":"Fama tanfaAAuhum shafaAAatu ashshafiAAeen","juz":29,"page":577},{"s":74,"a":49,"key":"74:49","ar":"فَمَا لَهُمْ عَنِ ٱلتَّذْكِرَةِ مُعْرِضِينَ","en":"Then what is [the matter] with them that they are, from the reminder, turning away.","tr":"Fama lahum AAani attathkiratimuAArideen","juz":29,"page":577},{"s":74,"a":50,"key":"74:50","ar":"كَأَنَّهُمْ حُمُرٌ مُّسْتَنفِرَةٌ","en":"As if they were alarmed donkeys.","tr":"Kaannahum humurun mustanfira","juz":29,"page":577},{"s":74,"a":51,"key":"74:51","ar":"فَرَّتْ مِن قَسْوَرَةٍۭ","en":"Fleeing from a lion?","tr":"Farrat min qaswara","juz":29,"page":577},{"s":74,"a":52,"key":"74:52","ar":"بَلْ يُرِيدُ كُلُّ ٱمْرِئٍ مِّنْهُمْ أَن يُؤْتَىٰ صُحُفًا مُّنَشَّرَةً","en":"Rather, every person among them desires that he1 would be given scriptures spread about.2","tr":"Bal yureedu kullu imri-in minhum an yu/tasuhufan munashshara","juz":29,"page":577},{"s":74,"a":53,"key":"74:53","ar":"كَلَّا ۖ بَل لَّا يَخَافُونَ ٱلْـَٔاخِرَةَ","en":"No! But they do not fear the Hereafter.","tr":"Kalla bal la yakhafoonaal-akhira","juz":29,"page":577},{"s":74,"a":54,"key":"74:54","ar":"كَلَّآ إِنَّهُۥ تَذْكِرَةٌ","en":"No! Indeed, it [i.e., the Qur’ān] is a reminder.","tr":"Kalla innahu tathkira","juz":29,"page":577},{"s":74,"a":55,"key":"74:55","ar":"فَمَن شَآءَ ذَكَرَهُۥ","en":"Then whoever wills will remember it.","tr":"Faman shaa thakarah","juz":29,"page":577},{"s":74,"a":56,"key":"74:56","ar":"وَمَا يَذْكُرُونَ إِلَّآ أَن يَشَآءَ ٱللَّهُ ۚ هُوَ أَهْلُ ٱلتَّقْوَىٰ وَأَهْلُ ٱلْمَغْفِرَةِ","en":"And they will not remember except that Allāh wills. He is worthy of fear and adequate for [granting] forgiveness.","tr":"Wama yathkuroona illaan yashaa Allahu huwa ahlu attaqwawaahlu almaghfirat","juz":29,"page":577},{"s":75,"a":1,"key":"75:1","ar":" لَآ أُقْسِمُ بِيَوْمِ ٱلْقِيَـٰمَةِ","en":"I swear by the Day of Resurrection","tr":"La oqsimu biyawmi alqiyamat","juz":29,"page":577},{"s":75,"a":2,"key":"75:2","ar":"وَلَآ أُقْسِمُ بِٱلنَّفْسِ ٱللَّوَّامَةِ","en":"And I swear by the reproaching soul1 [to the certainty of resurrection].","tr":"Wala oqsimu binnafsi allawwamat","juz":29,"page":577},{"s":75,"a":3,"key":"75:3","ar":"أَيَحْسَبُ ٱلْإِنسَـٰنُ أَلَّن نَّجْمَعَ عِظَامَهُۥ","en":"Does man think that We will not assemble his bones?","tr":"Ayahsabu al-insanu allannajmaAAa AAithamah","juz":29,"page":577},{"s":75,"a":4,"key":"75:4","ar":"بَلَىٰ قَـٰدِرِينَ عَلَىٰٓ أَن نُّسَوِّىَ بَنَانَهُۥ","en":"Yes. [We are] Able [even] to proportion his fingertips.","tr":"Bala qadireena AAala annusawwiya bananah","juz":29,"page":577},{"s":75,"a":5,"key":"75:5","ar":"بَلْ يُرِيدُ ٱلْإِنسَـٰنُ لِيَفْجُرَ أَمَامَهُۥ","en":"But man desires to continue in sin.1","tr":"Bal yureedu al-insanu liyafjura amamah","juz":29,"page":577},{"s":75,"a":6,"key":"75:6","ar":"يَسْـَٔلُ أَيَّانَ يَوْمُ ٱلْقِيَـٰمَةِ","en":"He asks, \"When is the Day of Resurrection?\"","tr":"Yas-alu ayyana yawmu alqiyama","juz":29,"page":577},{"s":75,"a":7,"key":"75:7","ar":"فَإِذَا بَرِقَ ٱلْبَصَرُ","en":"So when vision is dazzled.","tr":"Fa-itha bariqa albasar","juz":29,"page":577},{"s":75,"a":8,"key":"75:8","ar":"وَخَسَفَ ٱلْقَمَرُ","en":"And the moon darkens.","tr":"Wakhasafa alqamar","juz":29,"page":577},{"s":75,"a":9,"key":"75:9","ar":"وَجُمِعَ ٱلشَّمْسُ وَٱلْقَمَرُ","en":"And the sun and the moon are joined,","tr":"WajumiAAa ashshamsu walqamar","juz":29,"page":577},{"s":75,"a":10,"key":"75:10","ar":"يَقُولُ ٱلْإِنسَـٰنُ يَوْمَئِذٍ أَيْنَ ٱلْمَفَرُّ","en":"Man will say on that Day, \"Where is the [place of] escape?\"","tr":"Yaqoolu al-insanu yawma-ithinayna almafar","juz":29,"page":577},{"s":75,"a":11,"key":"75:11","ar":"كَلَّا لَا وَزَرَ","en":"No! There is no refuge.","tr":"Kalla la wazar","juz":29,"page":577},{"s":75,"a":12,"key":"75:12","ar":"إِلَىٰ رَبِّكَ يَوْمَئِذٍ ٱلْمُسْتَقَرُّ","en":"To your Lord, that Day, is the [place of] permanence.","tr":"Ila rabbika yawma-ithinalmustaqar","juz":29,"page":577},{"s":75,"a":13,"key":"75:13","ar":"يُنَبَّؤُا۟ ٱلْإِنسَـٰنُ يَوْمَئِذٍۭ بِمَا قَدَّمَ وَأَخَّرَ","en":"Man will be informed that Day of what he sent ahead1 and kept back.2","tr":"Yunabbao al-insanu yawma-ithinbima qaddama waakhkhar","juz":29,"page":577},{"s":75,"a":14,"key":"75:14","ar":"بَلِ ٱلْإِنسَـٰنُ عَلَىٰ نَفْسِهِۦ بَصِيرَةٌ","en":"Rather, man, against himself, will be a witness,1","tr":"Bali al-insanu AAala nafsihibaseera","juz":29,"page":577},{"s":75,"a":15,"key":"75:15","ar":"وَلَوْ أَلْقَىٰ مَعَاذِيرَهُۥ","en":"Even if he presents his excuses.","tr":"Walaw alqa maAAatheerah","juz":29,"page":577},{"s":75,"a":16,"key":"75:16","ar":"لَا تُحَرِّكْ بِهِۦ لِسَانَكَ لِتَعْجَلَ بِهِۦٓ","en":"Move not your tongue with it, [O Muḥammad], to hasten with it [i.e., recitation of the Qur’ān].","tr":"La tuharrik bihi lisanakalitaAAjala bih","juz":29,"page":577},{"s":75,"a":17,"key":"75:17","ar":"إِنَّ عَلَيْنَا جَمْعَهُۥ وَقُرْءَانَهُۥ","en":"Indeed, upon Us is its collection [in your heart] and [to make possible] its recitation.","tr":"Inna AAalayna jamAAahu waqur-anah","juz":29,"page":577},{"s":75,"a":18,"key":"75:18","ar":"فَإِذَا قَرَأْنَـٰهُ فَٱتَّبِعْ قُرْءَانَهُۥ","en":"So when We have recited it [through Gabriel], then follow its recitation.","tr":"Fa-itha qara/nahu fattabiAAqur-anah","juz":29,"page":577},{"s":75,"a":19,"key":"75:19","ar":"ثُمَّ إِنَّ عَلَيْنَا بَيَانَهُۥ","en":"Then upon Us is its clarification [to you].","tr":"Thumma inna AAalayna bayanah","juz":29,"page":577},{"s":75,"a":20,"key":"75:20","ar":"كَلَّا بَلْ تُحِبُّونَ ٱلْعَاجِلَةَ","en":"No! But you [i.e., mankind] love the immediate","tr":"Kalla bal tuhibboona alAAajila","juz":29,"page":578},{"s":75,"a":21,"key":"75:21","ar":"وَتَذَرُونَ ٱلْـَٔاخِرَةَ","en":"And leave [i.e., neglect] the Hereafter.","tr":"Watatharoona al-akhira","juz":29,"page":578},{"s":75,"a":22,"key":"75:22","ar":"وُجُوهٌ يَوْمَئِذٍ نَّاضِرَةٌ","en":"[Some] faces, that Day, will be radiant,","tr":"Wujoohun yawma-ithin nadira","juz":29,"page":578},{"s":75,"a":23,"key":"75:23","ar":"إِلَىٰ رَبِّهَا نَاظِرَةٌ","en":"Looking at their Lord.1","tr":"Ila rabbiha nathira","juz":29,"page":578},{"s":75,"a":24,"key":"75:24","ar":"وَوُجُوهٌ يَوْمَئِذٍۭ بَاسِرَةٌ","en":"And [some] faces, that Day, will be contorted,","tr":"Wawujoohun yawma-ithin basira","juz":29,"page":578},{"s":75,"a":25,"key":"75:25","ar":"تَظُنُّ أَن يُفْعَلَ بِهَا فَاقِرَةٌ","en":"Expecting that there will be done to them [something] backbreaking.","tr":"Tathunnu an yufAAala bihafaqira","juz":29,"page":578},{"s":75,"a":26,"key":"75:26","ar":"كَلَّآ إِذَا بَلَغَتِ ٱلتَّرَاقِىَ","en":"No! When it [i.e., the soul] has reached the collar bones1","tr":"Kalla itha balaghati attaraqiy","juz":29,"page":578},{"s":75,"a":27,"key":"75:27","ar":"وَقِيلَ مَنْ ۜ رَاقٍ","en":"And it is said, \"Who will cure [him]?\"","tr":"Waqeela man raq","juz":29,"page":578},{"s":75,"a":28,"key":"75:28","ar":"وَظَنَّ أَنَّهُ ٱلْفِرَاقُ","en":"And he [i.e., the dying one] is certain that it is the [time of] separation","tr":"Wathanna annahu alfiraq","juz":29,"page":578},{"s":75,"a":29,"key":"75:29","ar":"وَٱلْتَفَّتِ ٱلسَّاقُ بِٱلسَّاقِ","en":"And the leg is wound about the leg,1","tr":"Waltaffati assaqu bilssaq","juz":29,"page":578},{"s":75,"a":30,"key":"75:30","ar":"إِلَىٰ رَبِّكَ يَوْمَئِذٍ ٱلْمَسَاقُ","en":"To your Lord, that Day, will be the procession.1","tr":"Ila rabbika yawma-ithin almasaq","juz":29,"page":578},{"s":75,"a":31,"key":"75:31","ar":"فَلَا صَدَّقَ وَلَا صَلَّىٰ","en":"And he [i.e., the disbeliever] had not believed, nor had he prayed.","tr":"Fala saddaqa wala salla","juz":29,"page":578},{"s":75,"a":32,"key":"75:32","ar":"وَلَـٰكِن كَذَّبَ وَتَوَلَّىٰ","en":"But [instead], he denied and turned away.","tr":"Walakin kaththaba watawalla","juz":29,"page":578},{"s":75,"a":33,"key":"75:33","ar":"ثُمَّ ذَهَبَ إِلَىٰٓ أَهْلِهِۦ يَتَمَطَّىٰٓ","en":"And then he went to his people, swaggering [in pride].","tr":"Thumma thahaba ila ahlihiyatamatta","juz":29,"page":578},{"s":75,"a":34,"key":"75:34","ar":"أَوْلَىٰ لَكَ فَأَوْلَىٰ","en":"Woe to you, and woe!","tr":"Awla laka faawla","juz":29,"page":578},{"s":75,"a":35,"key":"75:35","ar":"ثُمَّ أَوْلَىٰ لَكَ فَأَوْلَىٰٓ","en":"Then woe to you, and woe!","tr":"Thumma awla laka faawla","juz":29,"page":578},{"s":75,"a":36,"key":"75:36","ar":"أَيَحْسَبُ ٱلْإِنسَـٰنُ أَن يُتْرَكَ سُدًى","en":"Does man think that he will be left neglected?1","tr":"Ayahsabu al-insanu an yutrakasuda","juz":29,"page":578},{"s":75,"a":37,"key":"75:37","ar":"أَلَمْ يَكُ نُطْفَةً مِّن مَّنِىٍّ يُمْنَىٰ","en":"Had he not been a sperm from semen emitted?","tr":"Alam yaku nutfatan min manayyin yumna","juz":29,"page":578},{"s":75,"a":38,"key":"75:38","ar":"ثُمَّ كَانَ عَلَقَةً فَخَلَقَ فَسَوَّىٰ","en":"Then he was a clinging clot, and [Allāh] created [his form] and proportioned [him]","tr":"Thumma kana AAalaqatan fakhalaqafasawwa","juz":29,"page":578},{"s":75,"a":39,"key":"75:39","ar":"فَجَعَلَ مِنْهُ ٱلزَّوْجَيْنِ ٱلذَّكَرَ وَٱلْأُنثَىٰٓ","en":"And made of him two mates, the male and the female.","tr":"FajaAAala minhu azzawjayni aththakarawal-ontha","juz":29,"page":578},{"s":75,"a":40,"key":"75:40","ar":"أَلَيْسَ ذَٰلِكَ بِقَـٰدِرٍ عَلَىٰٓ أَن يُحْـِۧىَ ٱلْمَوْتَىٰ","en":"Is not that [Creator] Able to give life to the dead?","tr":"Alaysa thalika biqadirin AAalaan yuhyiya almawta","juz":29,"page":578},{"s":76,"a":1,"key":"76:1","ar":" هَلْ أَتَىٰ عَلَى ٱلْإِنسَـٰنِ حِينٌ مِّنَ ٱلدَّهْرِ لَمْ يَكُن شَيْـًٔا مَّذْكُورًا","en":"Has there [not] come upon man a period of time when he was not a thing [even] mentioned?","tr":"Hal ata AAala al-insani heenunmina addahri lam yakun shay-an mathkoora","juz":29,"page":578},{"s":76,"a":2,"key":"76:2","ar":"إِنَّا خَلَقْنَا ٱلْإِنسَـٰنَ مِن نُّطْفَةٍ أَمْشَاجٍ نَّبْتَلِيهِ فَجَعَلْنَـٰهُ سَمِيعًۢا بَصِيرًا","en":"Indeed, We created man from a sperm-drop mixture1 that We may try him; and We made him hearing and seeing.","tr":"Inna khalaqna al-insanamin nutfatin amshajin nabtaleehi fajaAAalnahusameeAAan baseera","juz":29,"page":578},{"s":76,"a":3,"key":"76:3","ar":"إِنَّا هَدَيْنَـٰهُ ٱلسَّبِيلَ إِمَّا شَاكِرًا وَإِمَّا كَفُورًا","en":"Indeed, We guided him to the way, be he grateful or be he ungrateful.","tr":"Inna hadaynahu assabeelaimma shakiran wa-imma kafoora","juz":29,"page":578},{"s":76,"a":4,"key":"76:4","ar":"إِنَّآ أَعْتَدْنَا لِلْكَـٰفِرِينَ سَلَـٰسِلَا۟ وَأَغْلَـٰلًا وَسَعِيرًا","en":"Indeed, We have prepared for the disbelievers chains and shackles and a blaze.","tr":"Inna aAAtadna lilkafireenasalasila waaghlalan wasaAAeera","juz":29,"page":578},{"s":76,"a":5,"key":"76:5","ar":"إِنَّ ٱلْأَبْرَارَ يَشْرَبُونَ مِن كَأْسٍ كَانَ مِزَاجُهَا كَافُورًا","en":"Indeed, the righteous will drink from a cup [of wine] whose mixture is of Kāfūr,1","tr":"Inna al-abrara yashraboona min ka/sinkana mizajuha kafoora","juz":29,"page":578},{"s":76,"a":6,"key":"76:6","ar":"عَيْنًا يَشْرَبُ بِهَا عِبَادُ ٱللَّهِ يُفَجِّرُونَهَا تَفْجِيرًا","en":"A spring of which the [righteous] servants of Allāh will drink; they will make it gush forth in force [and abundance].","tr":"AAaynan yashrabu biha AAibaduAllahi yufajjiroonaha tafjeera","juz":29,"page":579},{"s":76,"a":7,"key":"76:7","ar":"يُوفُونَ بِٱلنَّذْرِ وَيَخَافُونَ يَوْمًا كَانَ شَرُّهُۥ مُسْتَطِيرًا","en":"They [are those who] fulfill [their] vows and fear a Day whose evil will be widespread.","tr":"Yoofoona binnathri wayakhafoonayawman kana sharruhu mustateera","juz":29,"page":579},{"s":76,"a":8,"key":"76:8","ar":"وَيُطْعِمُونَ ٱلطَّعَامَ عَلَىٰ حُبِّهِۦ مِسْكِينًا وَيَتِيمًا وَأَسِيرًا","en":"And they give food in spite of love for it1 to the needy, the orphan, and the captive,","tr":"WayutAAimona attaAAamaAAala hubbihi miskeenan wayateeman waaseera","juz":29,"page":579},{"s":76,"a":9,"key":"76:9","ar":"إِنَّمَا نُطْعِمُكُمْ لِوَجْهِ ٱللَّهِ لَا نُرِيدُ مِنكُمْ جَزَآءً وَلَا شُكُورًا","en":"[Saying], \"We feed you only for the face [i.e., approval] of Allāh. We wish not from you reward or gratitude.","tr":"Innama nutAAimukum liwajhi Allahila nureedu minkum jazaan wala shukoora","juz":29,"page":579},{"s":76,"a":10,"key":"76:10","ar":"إِنَّا نَخَافُ مِن رَّبِّنَا يَوْمًا عَبُوسًا قَمْطَرِيرًا","en":"Indeed, We fear from our Lord a Day austere and distressful.\"","tr":"Inna nakhafu min rabbinayawman AAaboosan qamtareera","juz":29,"page":579},{"s":76,"a":11,"key":"76:11","ar":"فَوَقَىٰهُمُ ٱللَّهُ شَرَّ ذَٰلِكَ ٱلْيَوْمِ وَلَقَّىٰهُمْ نَضْرَةً وَسُرُورًا","en":"So Allāh will protect them from the evil of that Day and give them radiance and happiness","tr":"Fawaqahumu Allahu sharra thalikaalyawmi walaqqahum nadratan wasuroora","juz":29,"page":579},{"s":76,"a":12,"key":"76:12","ar":"وَجَزَىٰهُم بِمَا صَبَرُوا۟ جَنَّةً وَحَرِيرًا","en":"And will reward them for what they patiently endured [with] a garden [in Paradise] and silk [garments].","tr":"Wajazahum bima sabaroojannatan wahareera","juz":29,"page":579},{"s":76,"a":13,"key":"76:13","ar":"مُّتَّكِـِٔينَ فِيهَا عَلَى ٱلْأَرَآئِكِ ۖ لَا يَرَوْنَ فِيهَا شَمْسًا وَلَا زَمْهَرِيرًا","en":"[They will be] reclining therein on adorned couches. They will not see therein any [burning] sun or [freezing] cold.","tr":"Muttaki-eena feeha AAala al-ara-ikila yarawna feeha shamsan wala zamhareera","juz":29,"page":579},{"s":76,"a":14,"key":"76:14","ar":"وَدَانِيَةً عَلَيْهِمْ ظِلَـٰلُهَا وَذُلِّلَتْ قُطُوفُهَا تَذْلِيلًا","en":"And near above them are its shades, and its [fruit] to be picked will be lowered in compliance.","tr":"Wadaniyatan AAalayhim thilaluhawathullilat qutoofuha tathleela","juz":29,"page":579},{"s":76,"a":15,"key":"76:15","ar":"وَيُطَافُ عَلَيْهِم بِـَٔانِيَةٍ مِّن فِضَّةٍ وَأَكْوَابٍ كَانَتْ قَوَارِيرَا۠","en":"And there will be circulated among them vessels of silver and cups having been [created] clear [as glass],","tr":"Wayutafu AAalayhim bi-aniyatinmin fiddatin waakwabin kanat qawareera","juz":29,"page":579},{"s":76,"a":16,"key":"76:16","ar":"قَوَارِيرَا۟ مِن فِضَّةٍ قَدَّرُوهَا تَقْدِيرًا","en":"Clear glasses [made] from silver of which they have determined the measure.","tr":"Qawareera min fiddatinqaddarooha taqdeera","juz":29,"page":579},{"s":76,"a":17,"key":"76:17","ar":"وَيُسْقَوْنَ فِيهَا كَأْسًا كَانَ مِزَاجُهَا زَنجَبِيلًا","en":"And they will be given to drink a cup [of wine] whose mixture is of ginger","tr":"Wayusqawna feeha ka/san kanamizajuha zanjabeela","juz":29,"page":579},{"s":76,"a":18,"key":"76:18","ar":"عَيْنًا فِيهَا تُسَمَّىٰ سَلْسَبِيلًا","en":"[From] a fountain within it [i.e., Paradise] named Salsabeel.","tr":"AAaynan feeha tusammasalsabeela","juz":29,"page":579},{"s":76,"a":19,"key":"76:19","ar":"۞ وَيَطُوفُ عَلَيْهِمْ وِلْدَٰنٌ مُّخَلَّدُونَ إِذَا رَأَيْتَهُمْ حَسِبْتَهُمْ لُؤْلُؤًا مَّنثُورًا","en":"There will circulate among them young boys made eternal. When you see them, you would think them [as beautiful as] scattered pearls.","tr":"Wayatoofu AAalayhim wildanunmukhalladoona itha raaytahum hasibtahum lu/lu-anmanthoora","juz":29,"page":579},{"s":76,"a":20,"key":"76:20","ar":"وَإِذَا رَأَيْتَ ثَمَّ رَأَيْتَ نَعِيمًا وَمُلْكًا كَبِيرًا","en":"And when you look there [in Paradise], you will see pleasure and great dominion.","tr":"Wa-itha raayta thamma raaytanaAAeeman wamulkan kabeera","juz":29,"page":579},{"s":76,"a":21,"key":"76:21","ar":"عَـٰلِيَهُمْ ثِيَابُ سُندُسٍ خُضْرٌ وَإِسْتَبْرَقٌ ۖ وَحُلُّوٓا۟ أَسَاوِرَ مِن فِضَّةٍ وَسَقَىٰهُمْ رَبُّهُمْ شَرَابًا طَهُورًا","en":"Upon them [i.e., the inhabitants] will be green garments of fine silk and brocade. And they will be adorned with bracelets of silver, and their Lord will give them a purifying drink.","tr":"AAaliyahum thiyabu sundusinkhudrun wa-istabraqun wahulloo asawira minfiddatin wasaqahum rabbuhum sharaban tahoora","juz":29,"page":579},{"s":76,"a":22,"key":"76:22","ar":"إِنَّ هَـٰذَا كَانَ لَكُمْ جَزَآءً وَكَانَ سَعْيُكُم مَّشْكُورًا","en":"[And it will be said], \"Indeed, this is for you a reward, and your effort has been appreciated.\"","tr":"Inna hatha kana lakum jazaanwakana saAAyukum mashkoora","juz":29,"page":579},{"s":76,"a":23,"key":"76:23","ar":"إِنَّا نَحْنُ نَزَّلْنَا عَلَيْكَ ٱلْقُرْءَانَ تَنزِيلًا","en":"Indeed, it is We who have sent down to you, [O Muḥammad], the Qur’ān progressively.","tr":"Inna nahnu nazzalnaAAalayka alqur-ana tanzeela","juz":29,"page":579},{"s":76,"a":24,"key":"76:24","ar":"فَٱصْبِرْ لِحُكْمِ رَبِّكَ وَلَا تُطِعْ مِنْهُمْ ءَاثِمًا أَوْ كَفُورًا","en":"So be patient for the decision of your Lord and do not obey from among them a sinner or ungrateful [disbeliever].","tr":"Fasbir lihukmi rabbikawala tutiAA minhum athiman aw kafoora","juz":29,"page":579},{"s":76,"a":25,"key":"76:25","ar":"وَٱذْكُرِ ٱسْمَ رَبِّكَ بُكْرَةً وَأَصِيلًا","en":"And mention the name of your Lord [in prayer] morning and evening","tr":"Wathkuri isma rabbikabukratan waaseela","juz":29,"page":579},{"s":76,"a":26,"key":"76:26","ar":"وَمِنَ ٱلَّيْلِ فَٱسْجُدْ لَهُۥ وَسَبِّحْهُ لَيْلًا طَوِيلًا","en":"And during the night prostrate to Him and exalt [i.e., praise] Him a long [part of the] night.","tr":"Wamina allayli fasjud lahu wasabbihhulaylan taweela","juz":29,"page":580},{"s":76,"a":27,"key":"76:27","ar":"إِنَّ هَـٰٓؤُلَآءِ يُحِبُّونَ ٱلْعَاجِلَةَ وَيَذَرُونَ وَرَآءَهُمْ يَوْمًا ثَقِيلًا","en":"Indeed, these [disbelievers] love the immediate and leave behind them1 a grave Day.","tr":"Inna haola-i yuhibboonaalAAajilata wayatharoona waraahum yawmanthaqeela","juz":29,"page":580},{"s":76,"a":28,"key":"76:28","ar":"نَّحْنُ خَلَقْنَـٰهُمْ وَشَدَدْنَآ أَسْرَهُمْ ۖ وَإِذَا شِئْنَا بَدَّلْنَآ أَمْثَـٰلَهُمْ تَبْدِيلًا","en":"We have created them and strengthened their forms, and when We will, We can change their likenesses with [complete] alteration.","tr":"Nahnu khalaqnahum washadadnaasrahum wa-itha shi/na baddalna amthalahumtabdeela","juz":29,"page":580},{"s":76,"a":29,"key":"76:29","ar":"إِنَّ هَـٰذِهِۦ تَذْكِرَةٌ ۖ فَمَن شَآءَ ٱتَّخَذَ إِلَىٰ رَبِّهِۦ سَبِيلًا","en":"Indeed, this is a reminder, so he who wills may take to his Lord a way.","tr":"Inna hathihi tathkiratun famanshaa ittakhatha ila rabbihi sabeela","juz":29,"page":580},{"s":76,"a":30,"key":"76:30","ar":"وَمَا تَشَآءُونَ إِلَّآ أَن يَشَآءَ ٱللَّهُ ۚ إِنَّ ٱللَّهَ كَانَ عَلِيمًا حَكِيمًا","en":"And you do not will except that Allāh wills. Indeed, Allāh is ever Knowing and Wise.","tr":"Wama tashaoona illa anyashaa Allahu inna Allaha kanaAAaleeman hakeema","juz":29,"page":580},{"s":76,"a":31,"key":"76:31","ar":"يُدْخِلُ مَن يَشَآءُ فِى رَحْمَتِهِۦ ۚ وَٱلظَّـٰلِمِينَ أَعَدَّ لَهُمْ عَذَابًا أَلِيمًۢا","en":"He admits whom He wills into His mercy; but the wrongdoers - He has prepared for them a painful punishment.","tr":"Yudkhilu man yashao fee rahmatihiwaththalimeena aAAadda lahum AAathabanaleema","juz":29,"page":580},{"s":77,"a":1,"key":"77:1","ar":" وَٱلْمُرْسَلَـٰتِ عُرْفًا","en":"By those [winds] sent forth in gusts","tr":"Walmursalati AAurfa","juz":29,"page":580},{"s":77,"a":2,"key":"77:2","ar":"فَٱلْعَـٰصِفَـٰتِ عَصْفًا","en":"And the winds that blow violently","tr":"FalAAasifati AAasfa","juz":29,"page":580},{"s":77,"a":3,"key":"77:3","ar":"وَٱلنَّـٰشِرَٰتِ نَشْرًا","en":"And [by] the winds that spread [clouds]","tr":"Wannashirati nashra","juz":29,"page":580},{"s":77,"a":4,"key":"77:4","ar":"فَٱلْفَـٰرِقَـٰتِ فَرْقًا","en":"And those [angels] who bring criterion1","tr":"Falfariqati farqa","juz":29,"page":580},{"s":77,"a":5,"key":"77:5","ar":"فَٱلْمُلْقِيَـٰتِ ذِكْرًا","en":"And those [angels] who deliver a message.","tr":"Falmulqiyati thikra","juz":29,"page":580},{"s":77,"a":6,"key":"77:6","ar":"عُذْرًا أَوْ نُذْرًا","en":"As justification or warning,","tr":"AAuthran aw nuthra","juz":29,"page":580},{"s":77,"a":7,"key":"77:7","ar":"إِنَّمَا تُوعَدُونَ لَوَٰقِعٌ","en":"Indeed, what you are promised is to occur.","tr":"Innama tooAAadoona lawaqiAA","juz":29,"page":580},{"s":77,"a":8,"key":"77:8","ar":"فَإِذَا ٱلنُّجُومُ طُمِسَتْ","en":"So when the stars are obliterated","tr":"Fa-itha annujoomu tumisat","juz":29,"page":580},{"s":77,"a":9,"key":"77:9","ar":"وَإِذَا ٱلسَّمَآءُ فُرِجَتْ","en":"And when the heaven is opened","tr":"Wa-itha assamao furijat","juz":29,"page":580},{"s":77,"a":10,"key":"77:10","ar":"وَإِذَا ٱلْجِبَالُ نُسِفَتْ","en":"And when the mountains are blown away","tr":"Wa-itha aljibalu nusifat","juz":29,"page":580},{"s":77,"a":11,"key":"77:11","ar":"وَإِذَا ٱلرُّسُلُ أُقِّتَتْ","en":"And when the messengers' time has come...1","tr":"Wa-itha arrusulu oqqitat","juz":29,"page":580},{"s":77,"a":12,"key":"77:12","ar":"لِأَىِّ يَوْمٍ أُجِّلَتْ","en":"For what Day was it postponed?1","tr":"Li-ayyi yawmin ojjilat","juz":29,"page":580},{"s":77,"a":13,"key":"77:13","ar":"لِيَوْمِ ٱلْفَصْلِ","en":"For the Day of Judgement.","tr":"Liyawmi alfasl","juz":29,"page":580},{"s":77,"a":14,"key":"77:14","ar":"وَمَآ أَدْرَىٰكَ مَا يَوْمُ ٱلْفَصْلِ","en":"And what can make you know what is the Day of Judgement?","tr":"Wama adraka ma yawmualfasl","juz":29,"page":580},{"s":77,"a":15,"key":"77:15","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe,1 that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":580},{"s":77,"a":16,"key":"77:16","ar":"أَلَمْ نُهْلِكِ ٱلْأَوَّلِينَ","en":"Did We not destroy the former peoples?","tr":"Alam nuhliki al-awwaleen","juz":29,"page":580},{"s":77,"a":17,"key":"77:17","ar":"ثُمَّ نُتْبِعُهُمُ ٱلْـَٔاخِرِينَ","en":"Then We will follow them with the later ones.","tr":"Thumma nutbiAAuhumu al-akhireen","juz":29,"page":580},{"s":77,"a":18,"key":"77:18","ar":"كَذَٰلِكَ نَفْعَلُ بِٱلْمُجْرِمِينَ","en":"Thus do We deal with the criminals.","tr":"Kathalika nafAAalu bilmujrimeen","juz":29,"page":580},{"s":77,"a":19,"key":"77:19","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":580},{"s":77,"a":20,"key":"77:20","ar":"أَلَمْ نَخْلُقكُّم مِّن مَّآءٍ مَّهِينٍ","en":"Did We not create you from a liquid disdained?","tr":"Alam nakhluqkum min ma-in maheen","juz":29,"page":581},{"s":77,"a":21,"key":"77:21","ar":"فَجَعَلْنَـٰهُ فِى قَرَارٍ مَّكِينٍ","en":"And We placed it in a firm lodging [i.e., the womb]","tr":"FajaAAalnahu fee qararinmakeen","juz":29,"page":581},{"s":77,"a":22,"key":"77:22","ar":"إِلَىٰ قَدَرٍ مَّعْلُومٍ","en":"For a known extent.","tr":"Ila qadarin maAAloom","juz":29,"page":581},{"s":77,"a":23,"key":"77:23","ar":"فَقَدَرْنَا فَنِعْمَ ٱلْقَـٰدِرُونَ","en":"And We determined [it], and excellent [are We] to determine.","tr":"Faqadarna faniAAma alqadiroon","juz":29,"page":581},{"s":77,"a":24,"key":"77:24","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":581},{"s":77,"a":25,"key":"77:25","ar":"أَلَمْ نَجْعَلِ ٱلْأَرْضَ كِفَاتًا","en":"Have We not made the earth a container","tr":"Alam najAAali al-arda kifata","juz":29,"page":581},{"s":77,"a":26,"key":"77:26","ar":"أَحْيَآءً وَأَمْوَٰتًا","en":"Of the living and the dead?","tr":"Ahyaan waamwata","juz":29,"page":581},{"s":77,"a":27,"key":"77:27","ar":"وَجَعَلْنَا فِيهَا رَوَٰسِىَ شَـٰمِخَـٰتٍ وَأَسْقَيْنَـٰكُم مَّآءً فُرَاتًا","en":"And We placed therein lofty, firmly set mountains and have given you to drink sweet water.","tr":"WajaAAalna feeha rawasiyashamikhatin waasqaynakum maan furata","juz":29,"page":581},{"s":77,"a":28,"key":"77:28","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":581},{"s":77,"a":29,"key":"77:29","ar":"ٱنطَلِقُوٓا۟ إِلَىٰ مَا كُنتُم بِهِۦ تُكَذِّبُونَ","en":"[They will be told], \"Proceed to that which you used to deny.","tr":"Intaliqoo ila ma kuntumbihi tukaththiboon","juz":29,"page":581},{"s":77,"a":30,"key":"77:30","ar":"ٱنطَلِقُوٓا۟ إِلَىٰ ظِلٍّ ذِى ثَلَـٰثِ شُعَبٍ","en":"Proceed to a shadow [of smoke] having three columns.","tr":"Intaliqoo ila thillinthee thalathi shuAAab","juz":29,"page":581},{"s":77,"a":31,"key":"77:31","ar":"لَّا ظَلِيلٍ وَلَا يُغْنِى مِنَ ٱللَّهَبِ","en":"[But having] no cool shade and availing not against the flame.\"","tr":"La thaleelin walayughnee mina allahab","juz":29,"page":581},{"s":77,"a":32,"key":"77:32","ar":"إِنَّهَا تَرْمِى بِشَرَرٍ كَٱلْقَصْرِ","en":"Indeed, it throws sparks [as huge] as a fortress,","tr":"Innaha tarmee bishararin kalqasr","juz":29,"page":581},{"s":77,"a":33,"key":"77:33","ar":"كَأَنَّهُۥ جِمَـٰلَتٌ صُفْرٌ","en":"As if they were yellowish [black] camels.","tr":"Kaannahu jimalatun sufr","juz":29,"page":581},{"s":77,"a":34,"key":"77:34","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":581},{"s":77,"a":35,"key":"77:35","ar":"هَـٰذَا يَوْمُ لَا يَنطِقُونَ","en":"This is a Day they will not speak,","tr":"Hatha yawmu la yantiqoon","juz":29,"page":581},{"s":77,"a":36,"key":"77:36","ar":"وَلَا يُؤْذَنُ لَهُمْ فَيَعْتَذِرُونَ","en":"Nor will it be permitted for them to make an excuse.","tr":"Wala yu/thanu lahum fayaAAtathiroon","juz":29,"page":581},{"s":77,"a":37,"key":"77:37","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":581},{"s":77,"a":38,"key":"77:38","ar":"هَـٰذَا يَوْمُ ٱلْفَصْلِ ۖ جَمَعْنَـٰكُمْ وَٱلْأَوَّلِينَ","en":"This is the Day of Judgement; We will have assembled you and the former peoples.","tr":"Hatha yawmu alfasli jamaAAnakumwal-awwaleen","juz":29,"page":581},{"s":77,"a":39,"key":"77:39","ar":"فَإِن كَانَ لَكُمْ كَيْدٌ فَكِيدُونِ","en":"So if you have a plan, then plan against Me.","tr":"Fa-in kana lakum kaydun fakeedoon","juz":29,"page":581},{"s":77,"a":40,"key":"77:40","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":581},{"s":77,"a":41,"key":"77:41","ar":"إِنَّ ٱلْمُتَّقِينَ فِى ظِلَـٰلٍ وَعُيُونٍ","en":"Indeed, the righteous will be among shades and springs","tr":"Inna almuttaqeena fee thilalinwaAAuyoon","juz":29,"page":581},{"s":77,"a":42,"key":"77:42","ar":"وَفَوَٰكِهَ مِمَّا يَشْتَهُونَ","en":"And fruits from whatever they desire,","tr":"Wafawakiha mimma yashtahoon","juz":29,"page":581},{"s":77,"a":43,"key":"77:43","ar":"كُلُوا۟ وَٱشْرَبُوا۟ هَنِيٓـًٔۢا بِمَا كُنتُمْ تَعْمَلُونَ","en":"[Being told], \"Eat and drink in satisfaction for what you used to do.\"","tr":"Kuloo washraboo hanee-an bimakuntum taAAmaloon","juz":29,"page":581},{"s":77,"a":44,"key":"77:44","ar":"إِنَّا كَذَٰلِكَ نَجْزِى ٱلْمُحْسِنِينَ","en":"Indeed, We thus reward the doers of good.","tr":"Inna kathalika najzee almuhsineen","juz":29,"page":581},{"s":77,"a":45,"key":"77:45","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":581},{"s":77,"a":46,"key":"77:46","ar":"كُلُوا۟ وَتَمَتَّعُوا۟ قَلِيلًا إِنَّكُم مُّجْرِمُونَ","en":"[O disbelievers], eat and enjoy yourselves a little; indeed, you are criminals.","tr":"Kuloo watamattaAAoo qaleelan innakummujrimoon","juz":29,"page":581},{"s":77,"a":47,"key":"77:47","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":581},{"s":77,"a":48,"key":"77:48","ar":"وَإِذَا قِيلَ لَهُمُ ٱرْكَعُوا۟ لَا يَرْكَعُونَ","en":"And when it is said to them, \"Bow [in prayer],\" they do not bow.","tr":"Wa-itha qeela lahumu irkaAAoo layarkaAAoon","juz":29,"page":581},{"s":77,"a":49,"key":"77:49","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers.","tr":"Waylun yawma-ithin lilmukaththibeen","juz":29,"page":581},{"s":77,"a":50,"key":"77:50","ar":"فَبِأَىِّ حَدِيثٍۭ بَعْدَهُۥ يُؤْمِنُونَ","en":"Then in what statement after it [i.e., the Qur’ān] will they believe?","tr":"Fabi-ayyi hadeethin baAAdahuyu/minoon","juz":29,"page":581},{"s":78,"a":1,"key":"78:1","ar":" عَمَّ يَتَسَآءَلُونَ","en":"About what are they asking one another?","tr":"AAamma yatasaaloon","juz":30,"page":582},{"s":78,"a":2,"key":"78:2","ar":"عَنِ ٱلنَّبَإِ ٱلْعَظِيمِ","en":"About the great news1 -","tr":"AAani annaba-i alAAatheem","juz":30,"page":582},{"s":78,"a":3,"key":"78:3","ar":"ٱلَّذِى هُمْ فِيهِ مُخْتَلِفُونَ","en":"That over which they are in disagreement.","tr":"Allathee hum feehi mukhtalifoon","juz":30,"page":582},{"s":78,"a":4,"key":"78:4","ar":"كَلَّا سَيَعْلَمُونَ","en":"No! They are going to know.","tr":"Kalla sayaAAlamoon","juz":30,"page":582},{"s":78,"a":5,"key":"78:5","ar":"ثُمَّ كَلَّا سَيَعْلَمُونَ","en":"Then, no! They are going to know.","tr":"Thumma kalla sayaAAlamoon","juz":30,"page":582},{"s":78,"a":6,"key":"78:6","ar":"أَلَمْ نَجْعَلِ ٱلْأَرْضَ مِهَـٰدًا","en":"Have We not made the earth a resting place?","tr":"Alam najAAali al-arda mihada","juz":30,"page":582},{"s":78,"a":7,"key":"78:7","ar":"وَٱلْجِبَالَ أَوْتَادًا","en":"And the mountains as stakes?1","tr":"Waljibala awtada","juz":30,"page":582},{"s":78,"a":8,"key":"78:8","ar":"وَخَلَقْنَـٰكُمْ أَزْوَٰجًا","en":"And We created you in pairs.","tr":"Wakhalaqnakum azwaja","juz":30,"page":582},{"s":78,"a":9,"key":"78:9","ar":"وَجَعَلْنَا نَوْمَكُمْ سُبَاتًا","en":"And made your sleep [a means for] rest","tr":"WajaAAalna nawmakum subata","juz":30,"page":582},{"s":78,"a":10,"key":"78:10","ar":"وَجَعَلْنَا ٱلَّيْلَ لِبَاسًا","en":"And made the night as clothing1.","tr":"WajaAAalna allayla libasa","juz":30,"page":582},{"s":78,"a":11,"key":"78:11","ar":"وَجَعَلْنَا ٱلنَّهَارَ مَعَاشًا","en":"And made the day for livelihood.","tr":"WajaAAalna annaharamaAAasha","juz":30,"page":582},{"s":78,"a":12,"key":"78:12","ar":"وَبَنَيْنَا فَوْقَكُمْ سَبْعًا شِدَادًا","en":"And constructed above you seven strong [heavens].","tr":"Wabanayna fawqakum sabAAan shidada","juz":30,"page":582},{"s":78,"a":13,"key":"78:13","ar":"وَجَعَلْنَا سِرَاجًا وَهَّاجًا","en":"And made [therein] a burning lamp","tr":"WajaAAalna sirajan wahhaja","juz":30,"page":582},{"s":78,"a":14,"key":"78:14","ar":"وَأَنزَلْنَا مِنَ ٱلْمُعْصِرَٰتِ مَآءً ثَجَّاجًا","en":"And sent down, from the rain clouds, pouring water.","tr":"Waanzalna mina almuAAsiratimaan thajjaja","juz":30,"page":582},{"s":78,"a":15,"key":"78:15","ar":"لِّنُخْرِجَ بِهِۦ حَبًّا وَنَبَاتًا","en":"That We may bring forth thereby grain and vegetation.","tr":"Linukhrija bihi habban wanabata","juz":30,"page":582},{"s":78,"a":16,"key":"78:16","ar":"وَجَنَّـٰتٍ أَلْفَافًا","en":"And gardens of entwined growth.","tr":"Wajannatin alfafa","juz":30,"page":582},{"s":78,"a":17,"key":"78:17","ar":"إِنَّ يَوْمَ ٱلْفَصْلِ كَانَ مِيقَـٰتًا","en":"Indeed, the Day of Judgement is an appointed time -","tr":"Inna yawma alfasli kana meeqata","juz":30,"page":582},{"s":78,"a":18,"key":"78:18","ar":"يَوْمَ يُنفَخُ فِى ٱلصُّورِ فَتَأْتُونَ أَفْوَاجًا","en":"The Day the Horn is blown and you will come forth in multitudes","tr":"Yawma yunfakhu fee assoorifata/toona afwaja","juz":30,"page":582},{"s":78,"a":19,"key":"78:19","ar":"وَفُتِحَتِ ٱلسَّمَآءُ فَكَانَتْ أَبْوَٰبًا","en":"And the heaven is opened and will become gateways.","tr":"Wafutihati assamao fakanatabwaba","juz":30,"page":582},{"s":78,"a":20,"key":"78:20","ar":"وَسُيِّرَتِ ٱلْجِبَالُ فَكَانَتْ سَرَابًا","en":"And the mountains are removed and will be [but] a mirage.","tr":"Wasuyyirati aljibalu fakanatsaraba","juz":30,"page":582},{"s":78,"a":21,"key":"78:21","ar":"إِنَّ جَهَنَّمَ كَانَتْ مِرْصَادًا","en":"Indeed, Hell has been lying in wait","tr":"Inna jahannama kanat mirsada","juz":30,"page":582},{"s":78,"a":22,"key":"78:22","ar":"لِّلطَّـٰغِينَ مَـَٔابًا","en":"For the transgressors, a place of return,","tr":"Littagheena maaba","juz":30,"page":582},{"s":78,"a":23,"key":"78:23","ar":"لَّـٰبِثِينَ فِيهَآ أَحْقَابًا","en":"In which they will remain for ages [unending].","tr":"Labitheena feeha ahqaba","juz":30,"page":582},{"s":78,"a":24,"key":"78:24","ar":"لَّا يَذُوقُونَ فِيهَا بَرْدًا وَلَا شَرَابًا","en":"They will not taste therein [any] coolness or drink.","tr":"La yathooqoona feehabardan wala sharaba","juz":30,"page":582},{"s":78,"a":25,"key":"78:25","ar":"إِلَّا حَمِيمًا وَغَسَّاقًا","en":"Except scalding water and [foul] purulence -","tr":"Illa hameeman waghassaqa","juz":30,"page":582},{"s":78,"a":26,"key":"78:26","ar":"جَزَآءً وِفَاقًا","en":"An appropriate recompense.1","tr":"Jazaan wifaqa","juz":30,"page":582},{"s":78,"a":27,"key":"78:27","ar":"إِنَّهُمْ كَانُوا۟ لَا يَرْجُونَ حِسَابًا","en":"Indeed, they were not expecting an account","tr":"Innahum kanoo la yarjoona hisaba","juz":30,"page":582},{"s":78,"a":28,"key":"78:28","ar":"وَكَذَّبُوا۟ بِـَٔايَـٰتِنَا كِذَّابًا","en":"And denied Our verses with [emphatic] denial.","tr":"Wakaththaboo bi-ayatinakiththaba","juz":30,"page":582},{"s":78,"a":29,"key":"78:29","ar":"وَكُلَّ شَىْءٍ أَحْصَيْنَـٰهُ كِتَـٰبًا","en":"But all things We have enumerated in writing.","tr":"Wakulla shay-in ahsaynahu kitaba","juz":30,"page":582},{"s":78,"a":30,"key":"78:30","ar":"فَذُوقُوا۟ فَلَن نَّزِيدَكُمْ إِلَّا عَذَابًا","en":"\"So taste [the penalty], and never will We increase you except in torment.\"1","tr":"Fathooqoo falan nazeedakum illaAAathaba","juz":30,"page":582},{"s":78,"a":31,"key":"78:31","ar":"إِنَّ لِلْمُتَّقِينَ مَفَازًا","en":"Indeed, for the righteous is attainment1 -","tr":"Inna lilmuttaqeena mafaza","juz":30,"page":583},{"s":78,"a":32,"key":"78:32","ar":"حَدَآئِقَ وَأَعْنَـٰبًا","en":"Gardens and grapevines.","tr":"Hada-iqa waaAAnaba","juz":30,"page":583},{"s":78,"a":33,"key":"78:33","ar":"وَكَوَاعِبَ أَتْرَابًا","en":"And full-breasted [companions] of equal age.","tr":"WakawaAAiba atraba","juz":30,"page":583},{"s":78,"a":34,"key":"78:34","ar":"وَكَأْسًا دِهَاقًا","en":"And a full cup.1","tr":"Waka/san dihaqa","juz":30,"page":583},{"s":78,"a":35,"key":"78:35","ar":"لَّا يَسْمَعُونَ فِيهَا لَغْوًا وَلَا كِذَّٰبًا","en":"No ill speech will they hear therein or any falsehood -","tr":"La yasmaAAoona feeha laghwanwala kiththaba","juz":30,"page":583},{"s":78,"a":36,"key":"78:36","ar":"جَزَآءً مِّن رَّبِّكَ عَطَآءً حِسَابًا","en":"[As] reward from your Lord, [a generous] gift [made due by] account,1","tr":"Jazaan min rabbika AAataan hisaba","juz":30,"page":583},{"s":78,"a":37,"key":"78:37","ar":"رَّبِّ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ وَمَا بَيْنَهُمَا ٱلرَّحْمَـٰنِ ۖ لَا يَمْلِكُونَ مِنْهُ خِطَابًا","en":"[From] the Lord of the heavens and the earth and whatever is between them, the Most Merciful. They possess not from Him [authority for] speech.1","tr":"Rabbi assamawati wal-ardiwama baynahuma arrahmani layamlikoona minhu khitaba","juz":30,"page":583},{"s":78,"a":38,"key":"78:38","ar":"يَوْمَ يَقُومُ ٱلرُّوحُ وَٱلْمَلَـٰٓئِكَةُ صَفًّا ۖ لَّا يَتَكَلَّمُونَ إِلَّا مَنْ أَذِنَ لَهُ ٱلرَّحْمَـٰنُ وَقَالَ صَوَابًا","en":"The Day that the Spirit [i.e., Gabriel] and the angels will stand in rows, they will not speak except for one whom the Most Merciful permits, and he will say what is correct.","tr":"Yawma yaqoomu arroohu walmala-ikatusaffan la yatakallamoona illa man athinalahu arrahmanu waqala sawaba","juz":30,"page":583},{"s":78,"a":39,"key":"78:39","ar":"ذَٰلِكَ ٱلْيَوْمُ ٱلْحَقُّ ۖ فَمَن شَآءَ ٱتَّخَذَ إِلَىٰ رَبِّهِۦ مَـَٔابًا","en":"That is the True [i.e., certain] Day; so he who wills may take to his Lord a [way of] return.1","tr":"Thalika alyawmu alhaqqu famanshaa ittakhatha ila rabbihi maaba","juz":30,"page":583},{"s":78,"a":40,"key":"78:40","ar":"إِنَّآ أَنذَرْنَـٰكُمْ عَذَابًا قَرِيبًا يَوْمَ يَنظُرُ ٱلْمَرْءُ مَا قَدَّمَتْ يَدَاهُ وَيَقُولُ ٱلْكَافِرُ يَـٰلَيْتَنِى كُنتُ تُرَٰبًۢا","en":"Indeed, We have warned you of an impending punishment on the Day when a man will observe what his hands have put forth1 and the disbeliever will say, \"Oh, I wish that I were dust!\"","tr":"Inna antharnakum AAathabanqareeban yawma yanthuru almaro ma qaddamatyadahu wayaqoolu alkafiru ya laytanee kuntuturaba","juz":30,"page":583},{"s":79,"a":1,"key":"79:1","ar":" وَٱلنَّـٰزِعَـٰتِ غَرْقًا","en":"By those [angels] who extract with violence1","tr":"WannaziAAati gharqa","juz":30,"page":583},{"s":79,"a":2,"key":"79:2","ar":"وَٱلنَّـٰشِطَـٰتِ نَشْطًا","en":"And [by] those who remove with ease1","tr":"Wannashitati nashta","juz":30,"page":583},{"s":79,"a":3,"key":"79:3","ar":"وَٱلسَّـٰبِحَـٰتِ سَبْحًا","en":"And [by] those who glide [as if] swimming1","tr":"Wassabihati sabha","juz":30,"page":583},{"s":79,"a":4,"key":"79:4","ar":"فَٱلسَّـٰبِقَـٰتِ سَبْقًا","en":"And those who race each other in a race1","tr":"Fassabiqati sabqa","juz":30,"page":583},{"s":79,"a":5,"key":"79:5","ar":"فَٱلْمُدَبِّرَٰتِ أَمْرًا","en":"And those who arrange [each] matter,1","tr":"Falmudabbirati amra","juz":30,"page":583},{"s":79,"a":6,"key":"79:6","ar":"يَوْمَ تَرْجُفُ ٱلرَّاجِفَةُ","en":"On the Day the blast [of the Horn] will convulse [creation],","tr":"Yawma tarjufu arrajifa","juz":30,"page":583},{"s":79,"a":7,"key":"79:7","ar":"تَتْبَعُهَا ٱلرَّادِفَةُ","en":"There will follow it the subsequent [one].","tr":"TatbaAAuha arradifa","juz":30,"page":583},{"s":79,"a":8,"key":"79:8","ar":"قُلُوبٌ يَوْمَئِذٍ وَاجِفَةٌ","en":"Hearts,1 that Day, will tremble,","tr":"Quloobun yawma-ithin wajifa","juz":30,"page":583},{"s":79,"a":9,"key":"79:9","ar":"أَبْصَـٰرُهَا خَـٰشِعَةٌ","en":"Their eyes1 humbled.","tr":"Absaruha khashiAAa","juz":30,"page":583},{"s":79,"a":10,"key":"79:10","ar":"يَقُولُونَ أَءِنَّا لَمَرْدُودُونَ فِى ٱلْحَافِرَةِ","en":"They are [presently] saying, \"Will we indeed be returned to [our] former state [of life]?","tr":"Yaqooloona a-inna lamardoodoona feealhafira","juz":30,"page":583},{"s":79,"a":11,"key":"79:11","ar":"أَءِذَا كُنَّا عِظَـٰمًا نَّخِرَةً","en":"Even if we should be decayed bones?\"1","tr":"A-itha kunna AAithamannakhira","juz":30,"page":583},{"s":79,"a":12,"key":"79:12","ar":"قَالُوا۟ تِلْكَ إِذًا كَرَّةٌ خَاسِرَةٌ","en":"They say, \"That, then, would be a losing return.\"1","tr":"Qaloo tilka ithan karratun khasira","juz":30,"page":583},{"s":79,"a":13,"key":"79:13","ar":"فَإِنَّمَا هِىَ زَجْرَةٌ وَٰحِدَةٌ","en":"Indeed, it will be but one shout,","tr":"Fa-innama hiya zajratun wahida","juz":30,"page":583},{"s":79,"a":14,"key":"79:14","ar":"فَإِذَا هُم بِٱلسَّاهِرَةِ","en":"And suddenly they will be [alert] upon the earth's surface.","tr":"Fa-itha hum bissahira","juz":30,"page":583},{"s":79,"a":15,"key":"79:15","ar":"هَلْ أَتَىٰكَ حَدِيثُ مُوسَىٰٓ","en":"Has there reached you the story of Moses? -","tr":"Hal ataka hadeethu moosa","juz":30,"page":583},{"s":79,"a":16,"key":"79:16","ar":"إِذْ نَادَىٰهُ رَبُّهُۥ بِٱلْوَادِ ٱلْمُقَدَّسِ طُوًى","en":"When his Lord called to him in the sacred valley of Ṭuwā,","tr":"Ith nadahu rabbuhu bilwadialmuqaddasi tuwa","juz":30,"page":584},{"s":79,"a":17,"key":"79:17","ar":"ٱذْهَبْ إِلَىٰ فِرْعَوْنَ إِنَّهُۥ طَغَىٰ","en":"\"Go to Pharaoh. Indeed, he has transgressed.","tr":"Ithhab ila firAAawna innahu tagha","juz":30,"page":584},{"s":79,"a":18,"key":"79:18","ar":"فَقُلْ هَل لَّكَ إِلَىٰٓ أَن تَزَكَّىٰ","en":"And say to him, 'Would you [be willing to] purify yourself","tr":"Faqul hal laka ila an tazakka","juz":30,"page":584},{"s":79,"a":19,"key":"79:19","ar":"وَأَهْدِيَكَ إِلَىٰ رَبِّكَ فَتَخْشَىٰ","en":"And let me guide you to your Lord so you would fear [Him]?'\"","tr":"Waahdiyaka ila rabbika fatakhsha","juz":30,"page":584},{"s":79,"a":20,"key":"79:20","ar":"فَأَرَىٰهُ ٱلْـَٔايَةَ ٱلْكُبْرَىٰ","en":"And he showed him the greatest sign,1","tr":"Faarahu al-ayata alkubra","juz":30,"page":584},{"s":79,"a":21,"key":"79:21","ar":"فَكَذَّبَ وَعَصَىٰ","en":"But he [i.e., Pharaoh] denied and disobeyed.","tr":"Fakaththaba waAAasa","juz":30,"page":584},{"s":79,"a":22,"key":"79:22","ar":"ثُمَّ أَدْبَرَ يَسْعَىٰ","en":"Then he turned his back, striving [i.e., plotting].1","tr":"Thumma adbara yasAAa","juz":30,"page":584},{"s":79,"a":23,"key":"79:23","ar":"فَحَشَرَ فَنَادَىٰ","en":"And he gathered [his people] and called out.","tr":"Fahashara fanada","juz":30,"page":584},{"s":79,"a":24,"key":"79:24","ar":"فَقَالَ أَنَا۠ رَبُّكُمُ ٱلْأَعْلَىٰ","en":"And said, \"I am your most exalted lord.\"","tr":"Faqala ana rabbukumu al-aAAla","juz":30,"page":584},{"s":79,"a":25,"key":"79:25","ar":"فَأَخَذَهُ ٱللَّهُ نَكَالَ ٱلْـَٔاخِرَةِ وَٱلْأُولَىٰٓ","en":"So Allāh seized him in exemplary punishment for the last and the first [transgression].1.","tr":"Faakhathahu Allahu nakalaal-akhirati wal-oola","juz":30,"page":584},{"s":79,"a":26,"key":"79:26","ar":"إِنَّ فِى ذَٰلِكَ لَعِبْرَةً لِّمَن يَخْشَىٰٓ","en":"Indeed in that is a lesson [i.e., warning] for whoever would fear [Allāh].","tr":"Inna fee thalika laAAibratan limanyakhsha","juz":30,"page":584},{"s":79,"a":27,"key":"79:27","ar":"ءَأَنتُمْ أَشَدُّ خَلْقًا أَمِ ٱلسَّمَآءُ ۚ بَنَىٰهَا","en":"Are you a more difficult creation or is the heaven? He [i.e., Allāh] constructed it.","tr":"Aantum ashaddu khalqan ami assamaobanaha","juz":30,"page":584},{"s":79,"a":28,"key":"79:28","ar":"رَفَعَ سَمْكَهَا فَسَوَّىٰهَا","en":"He raised its ceiling and proportioned it.","tr":"RafaAAa samkaha fasawwaha","juz":30,"page":584},{"s":79,"a":29,"key":"79:29","ar":"وَأَغْطَشَ لَيْلَهَا وَأَخْرَجَ ضُحَىٰهَا","en":"And He darkened its night and extracted its brightness.1","tr":"Waaghtasha laylaha waakhraja duhaha","juz":30,"page":584},{"s":79,"a":30,"key":"79:30","ar":"وَٱلْأَرْضَ بَعْدَ ذَٰلِكَ دَحَىٰهَآ","en":"And after that He spread the earth.","tr":"Wal-arda baAAda thalikadahaha","juz":30,"page":584},{"s":79,"a":31,"key":"79:31","ar":"أَخْرَجَ مِنْهَا مَآءَهَا وَمَرْعَىٰهَا","en":"He extracted from it its water and its pasture,","tr":"Akhraja minha maahawamarAAaha","juz":30,"page":584},{"s":79,"a":32,"key":"79:32","ar":"وَٱلْجِبَالَ أَرْسَىٰهَا","en":"And the mountains He set firmly","tr":"Waljibala arsaha","juz":30,"page":584},{"s":79,"a":33,"key":"79:33","ar":"مَتَـٰعًا لَّكُمْ وَلِأَنْعَـٰمِكُمْ","en":"As enjoyment [i.e., provision] for you and your grazing livestock.","tr":"MataAAan lakum wali-anAAamikum","juz":30,"page":584},{"s":79,"a":34,"key":"79:34","ar":"فَإِذَا جَآءَتِ ٱلطَّآمَّةُ ٱلْكُبْرَىٰ","en":"But when there comes the greatest Overwhelming Calamity1 -","tr":"Fa-itha jaati attammatualkubra","juz":30,"page":584},{"s":79,"a":35,"key":"79:35","ar":"يَوْمَ يَتَذَكَّرُ ٱلْإِنسَـٰنُ مَا سَعَىٰ","en":"The Day when man will remember that for which he strove,","tr":"Yawma yatathakkaru al-insanu masaAAa","juz":30,"page":584},{"s":79,"a":36,"key":"79:36","ar":"وَبُرِّزَتِ ٱلْجَحِيمُ لِمَن يَرَىٰ","en":"And Hellfire will be exposed for [all] those who see -","tr":"Waburrizati aljaheemu liman yara","juz":30,"page":584},{"s":79,"a":37,"key":"79:37","ar":"فَأَمَّا مَن طَغَىٰ","en":"So as for he who transgressed","tr":"Faamma man tagha","juz":30,"page":584},{"s":79,"a":38,"key":"79:38","ar":"وَءَاثَرَ ٱلْحَيَوٰةَ ٱلدُّنْيَا","en":"And preferred the life of the world,","tr":"Waathara alhayata addunya","juz":30,"page":584},{"s":79,"a":39,"key":"79:39","ar":"فَإِنَّ ٱلْجَحِيمَ هِىَ ٱلْمَأْوَىٰ","en":"Then indeed, Hellfire will be [his] refuge.","tr":"Fa-inna aljaheema hiya alma/wa","juz":30,"page":584},{"s":79,"a":40,"key":"79:40","ar":"وَأَمَّا مَنْ خَافَ مَقَامَ رَبِّهِۦ وَنَهَى ٱلنَّفْسَ عَنِ ٱلْهَوَىٰ","en":"But as for he who feared the position of his Lord1 and prevented the soul from [unlawful] inclination,","tr":"Waama man khafa maqamarabbihi wanaha annafsa AAani alhawa","juz":30,"page":584},{"s":79,"a":41,"key":"79:41","ar":"فَإِنَّ ٱلْجَنَّةَ هِىَ ٱلْمَأْوَىٰ","en":"Then indeed, Paradise will be [his] refuge.","tr":"Fa-inna aljannata hiya alma/wa","juz":30,"page":584},{"s":79,"a":42,"key":"79:42","ar":"يَسْـَٔلُونَكَ عَنِ ٱلسَّاعَةِ أَيَّانَ مُرْسَىٰهَا","en":"They ask you, [O Muḥammad], about the Hour: when is its arrival?1","tr":"Yas-aloonaka AAani assaAAatiayyana mursaha","juz":30,"page":584},{"s":79,"a":43,"key":"79:43","ar":"فِيمَ أَنتَ مِن ذِكْرَىٰهَآ","en":"In what [position] are you that you should mention it?1","tr":"Feema anta min thikraha","juz":30,"page":584},{"s":79,"a":44,"key":"79:44","ar":"إِلَىٰ رَبِّكَ مُنتَهَىٰهَآ","en":"To your Lord is its finality.1","tr":"Ila rabbika muntahaha","juz":30,"page":584},{"s":79,"a":45,"key":"79:45","ar":"إِنَّمَآ أَنتَ مُنذِرُ مَن يَخْشَىٰهَا","en":"You are only a warner for those who fear it.","tr":"Innama anta munthiru manyakhshaha","juz":30,"page":584},{"s":79,"a":46,"key":"79:46","ar":"كَأَنَّهُمْ يَوْمَ يَرَوْنَهَا لَمْ يَلْبَثُوٓا۟ إِلَّا عَشِيَّةً أَوْ ضُحَىٰهَا","en":"It will be, on the Day they see it,1 as though they had not remained [in the world] except for an afternoon or a morning thereof.","tr":"Kaannahum yawma yarawnaha lamyalbathoo illa AAashiyyatan aw duhaha","juz":30,"page":584},{"s":80,"a":1,"key":"80:1","ar":" عَبَسَ وَتَوَلَّىٰٓ","en":"He [i.e., the Prophet (ﷺ) ] frowned and turned away","tr":"AAabasa watawalla","juz":30,"page":585},{"s":80,"a":2,"key":"80:2","ar":"أَن جَآءَهُ ٱلْأَعْمَىٰ","en":"Because there came to him the blind man,1 [interrupting].","tr":"An jaahu al-aAAma","juz":30,"page":585},{"s":80,"a":3,"key":"80:3","ar":"وَمَا يُدْرِيكَ لَعَلَّهُۥ يَزَّكَّىٰٓ","en":"But what would make you perceive, [O Muḥammad], that perhaps he might be purified1","tr":"Wama yudreeka laAAallahu yazzakka","juz":30,"page":585},{"s":80,"a":4,"key":"80:4","ar":"أَوْ يَذَّكَّرُ فَتَنفَعَهُ ٱلذِّكْرَىٰٓ","en":"Or be reminded and the remembrance would benefit him?","tr":"Aw yaththakkaru fatanfaAAahu aththikra","juz":30,"page":585},{"s":80,"a":5,"key":"80:5","ar":"أَمَّا مَنِ ٱسْتَغْنَىٰ","en":"As for he who thinks himself without need,1","tr":"Amma mani istaghna","juz":30,"page":585},{"s":80,"a":6,"key":"80:6","ar":"فَأَنتَ لَهُۥ تَصَدَّىٰ","en":"To him you give attention.","tr":"Faanta lahu tasadda","juz":30,"page":585},{"s":80,"a":7,"key":"80:7","ar":"وَمَا عَلَيْكَ أَلَّا يَزَّكَّىٰ","en":"And not upon you [is any blame] if he will not be purified.1","tr":"Wama AAalayka alla yazzakka","juz":30,"page":585},{"s":80,"a":8,"key":"80:8","ar":"وَأَمَّا مَن جَآءَكَ يَسْعَىٰ","en":"But as for he who came to you striving [for knowledge]","tr":"Waamma man jaaka yasAAa","juz":30,"page":585},{"s":80,"a":9,"key":"80:9","ar":"وَهُوَ يَخْشَىٰ","en":"While he fears [Allāh],","tr":"Wahuwa yakhsha","juz":30,"page":585},{"s":80,"a":10,"key":"80:10","ar":"فَأَنتَ عَنْهُ تَلَهَّىٰ","en":"From him you are distracted.","tr":"Faanta AAanhu talahha","juz":30,"page":585},{"s":80,"a":11,"key":"80:11","ar":"كَلَّآ إِنَّهَا تَذْكِرَةٌ","en":"No! Indeed, they [i.e., these verses] are a reminder;","tr":"Kalla innaha tathkira","juz":30,"page":585},{"s":80,"a":12,"key":"80:12","ar":"فَمَن شَآءَ ذَكَرَهُۥ","en":"So whoever wills may remember it.1","tr":"Faman shaa thakarah","juz":30,"page":585},{"s":80,"a":13,"key":"80:13","ar":"فِى صُحُفٍ مُّكَرَّمَةٍ","en":"[It is recorded] in honored sheets,","tr":"Fee suhufin mukarrama","juz":30,"page":585},{"s":80,"a":14,"key":"80:14","ar":"مَّرْفُوعَةٍ مُّطَهَّرَةٍۭ","en":"Exalted and purified,","tr":"MarfooAAatin mutahhara","juz":30,"page":585},{"s":80,"a":15,"key":"80:15","ar":"بِأَيْدِى سَفَرَةٍ","en":"[Carried] by the hands of messenger-angels,","tr":"Bi-aydee safara","juz":30,"page":585},{"s":80,"a":16,"key":"80:16","ar":"كِرَامٍۭ بَرَرَةٍ","en":"Noble and dutiful.","tr":"Kiramin barara","juz":30,"page":585},{"s":80,"a":17,"key":"80:17","ar":"قُتِلَ ٱلْإِنسَـٰنُ مَآ أَكْفَرَهُۥ","en":"Destroyed [i.e., cursed] is man;1 how disbelieving is he.","tr":"Qutila al-insanu ma akfarah","juz":30,"page":585},{"s":80,"a":18,"key":"80:18","ar":"مِنْ أَىِّ شَىْءٍ خَلَقَهُۥ","en":"From what thing [i.e., substance] did He create him?","tr":"Min ayyi shay-in khalaqah","juz":30,"page":585},{"s":80,"a":19,"key":"80:19","ar":"مِن نُّطْفَةٍ خَلَقَهُۥ فَقَدَّرَهُۥ","en":"From a sperm-drop He created him and destined for him;1","tr":"Min nutfatin khalaqahu faqaddarah","juz":30,"page":585},{"s":80,"a":20,"key":"80:20","ar":"ثُمَّ ٱلسَّبِيلَ يَسَّرَهُۥ","en":"Then He eased the way for him;1","tr":"Thumma assabeela yassarah","juz":30,"page":585},{"s":80,"a":21,"key":"80:21","ar":"ثُمَّ أَمَاتَهُۥ فَأَقْبَرَهُۥ","en":"Then He causes his death and provides a grave for him.1","tr":"Thumma amatahu faaqbarah","juz":30,"page":585},{"s":80,"a":22,"key":"80:22","ar":"ثُمَّ إِذَا شَآءَ أَنشَرَهُۥ","en":"Then when He wills, He will resurrect him.","tr":"Thumma itha shaa ansharah","juz":30,"page":585},{"s":80,"a":23,"key":"80:23","ar":"كَلَّا لَمَّا يَقْضِ مَآ أَمَرَهُۥ","en":"No! He [i.e., man] has not yet accomplished what He commanded him.","tr":"Kalla lamma yaqdi maamarah","juz":30,"page":585},{"s":80,"a":24,"key":"80:24","ar":"فَلْيَنظُرِ ٱلْإِنسَـٰنُ إِلَىٰ طَعَامِهِۦٓ","en":"Then let mankind look at his food -","tr":"Falyanthuri al-insanuila taAAamih","juz":30,"page":585},{"s":80,"a":25,"key":"80:25","ar":"أَنَّا صَبَبْنَا ٱلْمَآءَ صَبًّا","en":"How We poured down water in torrents,","tr":"Anna sababna almaasabba","juz":30,"page":585},{"s":80,"a":26,"key":"80:26","ar":"ثُمَّ شَقَقْنَا ٱلْأَرْضَ شَقًّا","en":"Then We broke open the earth, splitting [it with sprouts],","tr":"Thumma shaqaqna al-arda shaqqa","juz":30,"page":585},{"s":80,"a":27,"key":"80:27","ar":"فَأَنۢبَتْنَا فِيهَا حَبًّا","en":"And caused to grow within it grain","tr":"Faanbatna feeha habba","juz":30,"page":585},{"s":80,"a":28,"key":"80:28","ar":"وَعِنَبًا وَقَضْبًا","en":"And grapes and herbage","tr":"WaAAinaban waqadba","juz":30,"page":585},{"s":80,"a":29,"key":"80:29","ar":"وَزَيْتُونًا وَنَخْلًا","en":"And olive and palm trees","tr":"Wazaytoonan wanakhla","juz":30,"page":585},{"s":80,"a":30,"key":"80:30","ar":"وَحَدَآئِقَ غُلْبًا","en":"And gardens of dense shrubbery","tr":"Wahada-iqa ghulba","juz":30,"page":585},{"s":80,"a":31,"key":"80:31","ar":"وَفَـٰكِهَةً وَأَبًّا","en":"And fruit and grass -","tr":"Wafakihatan waabba","juz":30,"page":585},{"s":80,"a":32,"key":"80:32","ar":"مَّتَـٰعًا لَّكُمْ وَلِأَنْعَـٰمِكُمْ","en":"[As] enjoyment [i.e., provision] for you and your grazing livestock.","tr":"MataAAan lakum wali-anAAamikum","juz":30,"page":585},{"s":80,"a":33,"key":"80:33","ar":"فَإِذَا جَآءَتِ ٱلصَّآخَّةُ","en":"But when there comes the Deafening Blast1","tr":"Fa-itha jaati assakhkha","juz":30,"page":585},{"s":80,"a":34,"key":"80:34","ar":"يَوْمَ يَفِرُّ ٱلْمَرْءُ مِنْ أَخِيهِ","en":"On the Day a man will flee from his brother","tr":"Yawma yafirru almaro min akheeh","juz":30,"page":585},{"s":80,"a":35,"key":"80:35","ar":"وَأُمِّهِۦ وَأَبِيهِ","en":"And his mother and his father","tr":"Waommihi waabeeh","juz":30,"page":585},{"s":80,"a":36,"key":"80:36","ar":"وَصَـٰحِبَتِهِۦ وَبَنِيهِ","en":"And his wife and his children,","tr":"Wasahibatihi wabaneeh","juz":30,"page":585},{"s":80,"a":37,"key":"80:37","ar":"لِكُلِّ ٱمْرِئٍ مِّنْهُمْ يَوْمَئِذٍ شَأْنٌ يُغْنِيهِ","en":"For every man, that Day, will be a matter adequate for him.1","tr":"Likulli imri-in minhum yawma-ithinsha/nun yughneeh","juz":30,"page":585},{"s":80,"a":38,"key":"80:38","ar":"وُجُوهٌ يَوْمَئِذٍ مُّسْفِرَةٌ","en":"[Some] faces, that Day, will be bright -","tr":"Wujoohun yawma-ithin musfira","juz":30,"page":585},{"s":80,"a":39,"key":"80:39","ar":"ضَاحِكَةٌ مُّسْتَبْشِرَةٌ","en":"Laughing, rejoicing at good news.","tr":"Dahikatun mustabshira","juz":30,"page":585},{"s":80,"a":40,"key":"80:40","ar":"وَوُجُوهٌ يَوْمَئِذٍ عَلَيْهَا غَبَرَةٌ","en":"And [other] faces, that Day, will have upon them dust.","tr":"Wawujoohun yawma-ithin AAalayhaghabara","juz":30,"page":585},{"s":80,"a":41,"key":"80:41","ar":"تَرْهَقُهَا قَتَرَةٌ","en":"Blackness will cover them.","tr":"Tarhaquha qatara","juz":30,"page":585},{"s":80,"a":42,"key":"80:42","ar":"أُو۟لَـٰٓئِكَ هُمُ ٱلْكَفَرَةُ ٱلْفَجَرَةُ","en":"Those are the disbelievers, the wicked ones.","tr":"Ola-ika humu alkafaratu alfajara","juz":30,"page":585},{"s":81,"a":1,"key":"81:1","ar":" إِذَا ٱلشَّمْسُ كُوِّرَتْ","en":"When the sun is wrapped up [in darkness]","tr":"Itha ashshamsu kuwwirat","juz":30,"page":586},{"s":81,"a":2,"key":"81:2","ar":"وَإِذَا ٱلنُّجُومُ ٱنكَدَرَتْ","en":"And when the stars fall, dispersing,","tr":"Wa-itha annujoomu inkadarat","juz":30,"page":586},{"s":81,"a":3,"key":"81:3","ar":"وَإِذَا ٱلْجِبَالُ سُيِّرَتْ","en":"And when the mountains are removed","tr":"Wa-itha aljibalu suyyirat","juz":30,"page":586},{"s":81,"a":4,"key":"81:4","ar":"وَإِذَا ٱلْعِشَارُ عُطِّلَتْ","en":"And when full-term she-camels1 are neglected","tr":"Wa-itha alAAisharu AAuttilat","juz":30,"page":586},{"s":81,"a":5,"key":"81:5","ar":"وَإِذَا ٱلْوُحُوشُ حُشِرَتْ","en":"And when the wild beasts are gathered","tr":"Wa-itha alwuhooshu hushirat","juz":30,"page":586},{"s":81,"a":6,"key":"81:6","ar":"وَإِذَا ٱلْبِحَارُ سُجِّرَتْ","en":"And when the seas are filled with flame1","tr":"Wa-itha albiharu sujjirat","juz":30,"page":586},{"s":81,"a":7,"key":"81:7","ar":"وَإِذَا ٱلنُّفُوسُ زُوِّجَتْ","en":"And when the souls are paired1","tr":"Wa-itha annufoosu zuwwijat","juz":30,"page":586},{"s":81,"a":8,"key":"81:8","ar":"وَإِذَا ٱلْمَوْءُۥدَةُ سُئِلَتْ","en":"And when the girl [who was] buried alive is asked","tr":"Wa-itha almawoodatu su-ilat","juz":30,"page":586},{"s":81,"a":9,"key":"81:9","ar":"بِأَىِّ ذَنۢبٍ قُتِلَتْ","en":"For what sin she was killed","tr":"Bi-ayyi thanbin qutilat","juz":30,"page":586},{"s":81,"a":10,"key":"81:10","ar":"وَإِذَا ٱلصُّحُفُ نُشِرَتْ","en":"And when the pages1 are spread [i.e., made public]","tr":"Wa-itha assuhufunushirat","juz":30,"page":586},{"s":81,"a":11,"key":"81:11","ar":"وَإِذَا ٱلسَّمَآءُ كُشِطَتْ","en":"And when the sky is stripped away","tr":"Wa-itha assamao kushitat","juz":30,"page":586},{"s":81,"a":12,"key":"81:12","ar":"وَإِذَا ٱلْجَحِيمُ سُعِّرَتْ","en":"And when Hellfire is set ablaze","tr":"Wa-itha aljaheemu suAAAAirat","juz":30,"page":586},{"s":81,"a":13,"key":"81:13","ar":"وَإِذَا ٱلْجَنَّةُ أُزْلِفَتْ","en":"And when Paradise is brought near,","tr":"Wa-itha aljannatu ozlifat","juz":30,"page":586},{"s":81,"a":14,"key":"81:14","ar":"عَلِمَتْ نَفْسٌ مَّآ أَحْضَرَتْ","en":"A soul will [then] know what it has brought [with it].1","tr":"AAalimat nafsun ma ahdarat","juz":30,"page":586},{"s":81,"a":15,"key":"81:15","ar":"فَلَآ أُقْسِمُ بِٱلْخُنَّسِ","en":"So I swear by the retreating stars -","tr":"Fala oqsimu bilkhunnas","juz":30,"page":586},{"s":81,"a":16,"key":"81:16","ar":"ٱلْجَوَارِ ٱلْكُنَّسِ","en":"Those that run [their courses] and disappear [i.e., set]","tr":"Aljawari alkunnas","juz":30,"page":586},{"s":81,"a":17,"key":"81:17","ar":"وَٱلَّيْلِ إِذَا عَسْعَسَ","en":"And by the night as it closes in1","tr":"Wallayli itha AAasAAas","juz":30,"page":586},{"s":81,"a":18,"key":"81:18","ar":"وَٱلصُّبْحِ إِذَا تَنَفَّسَ","en":"And by the dawn when it breathes [i.e., stirs]","tr":"Wassubhi ithatanaffas","juz":30,"page":586},{"s":81,"a":19,"key":"81:19","ar":"إِنَّهُۥ لَقَوْلُ رَسُولٍ كَرِيمٍ","en":"[That] indeed, it [i.e., the Qur’ān] is a word [conveyed by] a noble messenger [i.e., Gabriel]","tr":"Innahu laqawlu rasoolin kareem","juz":30,"page":586},{"s":81,"a":20,"key":"81:20","ar":"ذِى قُوَّةٍ عِندَ ذِى ٱلْعَرْشِ مَكِينٍ","en":"[Who is] possessed of power and with the Owner of the Throne, secure [in position],","tr":"Thee quwwatin AAinda theealAAarshi makeen","juz":30,"page":586},{"s":81,"a":21,"key":"81:21","ar":"مُّطَاعٍ ثَمَّ أَمِينٍ","en":"Obeyed there [in the heavens] and trustworthy.","tr":"MutaAAin thamma ameen","juz":30,"page":586},{"s":81,"a":22,"key":"81:22","ar":"وَمَا صَاحِبُكُم بِمَجْنُونٍ","en":"And your companion [i.e., Prophet Muḥammad (ﷺ) ] is not [at all] mad.1","tr":"Wama sahibukum bimajnoon","juz":30,"page":586},{"s":81,"a":23,"key":"81:23","ar":"وَلَقَدْ رَءَاهُ بِٱلْأُفُقِ ٱلْمُبِينِ","en":"And he has already seen him [i.e., Gabriel] in the clear horizon.1","tr":"Walaqad raahu bilofuqialmubeen","juz":30,"page":586},{"s":81,"a":24,"key":"81:24","ar":"وَمَا هُوَ عَلَى ٱلْغَيْبِ بِضَنِينٍ","en":"And he [i.e., Muḥammad (ﷺ)] is not a withholder of [knowledge of] the unseen.1","tr":"Wama huwa AAala alghaybi bidaneen","juz":30,"page":586},{"s":81,"a":25,"key":"81:25","ar":"وَمَا هُوَ بِقَوْلِ شَيْطَـٰنٍ رَّجِيمٍ","en":"And it [i.e., the Qur’ān] is not the word of a devil, expelled [from the heavens].","tr":"Wama huwa biqawli shaytaninrajeem","juz":30,"page":586},{"s":81,"a":26,"key":"81:26","ar":"فَأَيْنَ تَذْهَبُونَ","en":"So where are you going?1","tr":"Faayna tathhaboon","juz":30,"page":586},{"s":81,"a":27,"key":"81:27","ar":"إِنْ هُوَ إِلَّا ذِكْرٌ لِّلْعَـٰلَمِينَ","en":"It is not except a reminder to the worlds","tr":"In huwa illa thikrun lilAAalameen","juz":30,"page":586},{"s":81,"a":28,"key":"81:28","ar":"لِمَن شَآءَ مِنكُمْ أَن يَسْتَقِيمَ","en":"For whoever wills among you to take a right course.","tr":"Liman shaa minkum an yastaqeem","juz":30,"page":586},{"s":81,"a":29,"key":"81:29","ar":"وَمَا تَشَآءُونَ إِلَّآ أَن يَشَآءَ ٱللَّهُ رَبُّ ٱلْعَـٰلَمِينَ","en":"And you do not will except that Allāh wills - Lord of the worlds.","tr":"Wama tashaoona illa anyashaa Allahu rabbu alAAalameen","juz":30,"page":586},{"s":82,"a":1,"key":"82:1","ar":" إِذَا ٱلسَّمَآءُ ٱنفَطَرَتْ","en":"When the sky breaks apart","tr":"Itha assamao infatarat","juz":30,"page":587},{"s":82,"a":2,"key":"82:2","ar":"وَإِذَا ٱلْكَوَاكِبُ ٱنتَثَرَتْ","en":"And when the stars fall, scattering,","tr":"Wa-itha alkawakibu intatharat","juz":30,"page":587},{"s":82,"a":3,"key":"82:3","ar":"وَإِذَا ٱلْبِحَارُ فُجِّرَتْ","en":"And when the seas are erupted","tr":"Wa-itha albiharu fujjirat","juz":30,"page":587},{"s":82,"a":4,"key":"82:4","ar":"وَإِذَا ٱلْقُبُورُ بُعْثِرَتْ","en":"And when the [contents of] graves are scattered [i.e., exposed],","tr":"Wa-itha alqubooru buAAthirat","juz":30,"page":587},{"s":82,"a":5,"key":"82:5","ar":"عَلِمَتْ نَفْسٌ مَّا قَدَّمَتْ وَأَخَّرَتْ","en":"A soul will [then] know what it has put forth and kept back.","tr":"AAalimat nafsun ma qaddamatwaakhkharat","juz":30,"page":587},{"s":82,"a":6,"key":"82:6","ar":"يَـٰٓأَيُّهَا ٱلْإِنسَـٰنُ مَا غَرَّكَ بِرَبِّكَ ٱلْكَرِيمِ","en":"O mankind, what has deceived you concerning your Lord, the Generous,","tr":"Ya ayyuha al-insanu magharraka birabbika alkareem","juz":30,"page":587},{"s":82,"a":7,"key":"82:7","ar":"ٱلَّذِى خَلَقَكَ فَسَوَّىٰكَ فَعَدَلَكَ","en":"Who created you, proportioned you, and balanced you?","tr":"Allathee khalaqaka fasawwakafaAAadalak","juz":30,"page":587},{"s":82,"a":8,"key":"82:8","ar":"فِىٓ أَىِّ صُورَةٍ مَّا شَآءَ رَكَّبَكَ","en":"In whatever form He willed has He assembled you.","tr":"Fee ayyi sooratin ma shaarakkabak","juz":30,"page":587},{"s":82,"a":9,"key":"82:9","ar":"كَلَّا بَلْ تُكَذِّبُونَ بِٱلدِّينِ","en":"No! But you deny the Recompense.","tr":"Kalla bal tukaththiboona biddeen","juz":30,"page":587},{"s":82,"a":10,"key":"82:10","ar":"وَإِنَّ عَلَيْكُمْ لَحَـٰفِظِينَ","en":"And indeed, [appointed] over you are keepers,1","tr":"Wa-inna AAalaykum lahafitheen","juz":30,"page":587},{"s":82,"a":11,"key":"82:11","ar":"كِرَامًا كَـٰتِبِينَ","en":"Noble and recording;","tr":"Kiraman katibeen","juz":30,"page":587},{"s":82,"a":12,"key":"82:12","ar":"يَعْلَمُونَ مَا تَفْعَلُونَ","en":"They know whatever you do.","tr":"YaAAlamoona ma tafAAaloon","juz":30,"page":587},{"s":82,"a":13,"key":"82:13","ar":"إِنَّ ٱلْأَبْرَارَ لَفِى نَعِيمٍ","en":"Indeed, the righteous will be in pleasure,","tr":"Inna al-abrara lafee naAAeem","juz":30,"page":587},{"s":82,"a":14,"key":"82:14","ar":"وَإِنَّ ٱلْفُجَّارَ لَفِى جَحِيمٍ","en":"And indeed, the wicked will be in Hellfire.","tr":"Wa-inna alfujjara lafee jaheem","juz":30,"page":587},{"s":82,"a":15,"key":"82:15","ar":"يَصْلَوْنَهَا يَوْمَ ٱلدِّينِ","en":"They will [enter to] burn therein on the Day of Recompense,","tr":"Yaslawnaha yawma addeen","juz":30,"page":587},{"s":82,"a":16,"key":"82:16","ar":"وَمَا هُمْ عَنْهَا بِغَآئِبِينَ","en":"And never therefrom will they be absent.","tr":"Wama hum AAanha bigha-ibeen","juz":30,"page":587},{"s":82,"a":17,"key":"82:17","ar":"وَمَآ أَدْرَىٰكَ مَا يَوْمُ ٱلدِّينِ","en":"And what can make you know what is the Day of Recompense?","tr":"Wama adraka ma yawmu addeeni","juz":30,"page":587},{"s":82,"a":18,"key":"82:18","ar":"ثُمَّ مَآ أَدْرَىٰكَ مَا يَوْمُ ٱلدِّينِ","en":"Then, what can make you know what is the Day of Recompense?","tr":"Thumma ma adraka mayawmu addeen","juz":30,"page":587},{"s":82,"a":19,"key":"82:19","ar":"يَوْمَ لَا تَمْلِكُ نَفْسٌ لِّنَفْسٍ شَيْـًٔا ۖ وَٱلْأَمْرُ يَوْمَئِذٍ لِّلَّهِ","en":"It is the Day when a soul will not possess for another soul [power to do] a thing; and the command, that Day, is [entirely] with Allāh.","tr":"Yawma la tamliku nafsun linafsinshay-an wal-amru yawma-ithin lillah","juz":30,"page":587},{"s":83,"a":1,"key":"83:1","ar":" وَيْلٌ لِّلْمُطَفِّفِينَ","en":"Woe to those who give less [than due],1","tr":"Waylun lilmutaffifeen","juz":30,"page":587},{"s":83,"a":2,"key":"83:2","ar":"ٱلَّذِينَ إِذَا ٱكْتَالُوا۟ عَلَى ٱلنَّاسِ يَسْتَوْفُونَ","en":"Who, when they take a measure from people, take in full.","tr":"Allatheena itha iktalooAAala annasi yastawfoon","juz":30,"page":587},{"s":83,"a":3,"key":"83:3","ar":"وَإِذَا كَالُوهُمْ أَو وَّزَنُوهُمْ يُخْسِرُونَ","en":"But if they give by measure or by weight to them, they cause loss.","tr":"Wa-itha kaloohum aw wazanoohumyukhsiroon","juz":30,"page":587},{"s":83,"a":4,"key":"83:4","ar":"أَلَا يَظُنُّ أُو۟لَـٰٓئِكَ أَنَّهُم مَّبْعُوثُونَ","en":"Do they not think that they will be resurrected","tr":"Ala yathunnu ola-ikaannahum mabAAoothoon","juz":30,"page":587},{"s":83,"a":5,"key":"83:5","ar":"لِيَوْمٍ عَظِيمٍ","en":"For a tremendous Day -","tr":"Liyawmin AAatheem","juz":30,"page":587},{"s":83,"a":6,"key":"83:6","ar":"يَوْمَ يَقُومُ ٱلنَّاسُ لِرَبِّ ٱلْعَـٰلَمِينَ","en":"The Day when mankind will stand before the Lord of the worlds?","tr":"Yawma yaqoomu annasu lirabbialAAalameen","juz":30,"page":587},{"s":83,"a":7,"key":"83:7","ar":"كَلَّآ إِنَّ كِتَـٰبَ ٱلْفُجَّارِ لَفِى سِجِّينٍ","en":"No! Indeed, the record of the wicked is in sijjeen.","tr":"Kalla inna kitaba alfujjarilafee sijjeen","juz":30,"page":588},{"s":83,"a":8,"key":"83:8","ar":"وَمَآ أَدْرَىٰكَ مَا سِجِّينٌ","en":"And what can make you know what is sijjeen?","tr":"Wama adraka ma sijjeen","juz":30,"page":588},{"s":83,"a":9,"key":"83:9","ar":"كِتَـٰبٌ مَّرْقُومٌ","en":"It is [their destination1 recorded in] a register inscribed.","tr":"Kitabun marqoom","juz":30,"page":588},{"s":83,"a":10,"key":"83:10","ar":"وَيْلٌ يَوْمَئِذٍ لِّلْمُكَذِّبِينَ","en":"Woe, that Day, to the deniers,","tr":"Waylun yawma-ithin lilmukaththibeen","juz":30,"page":588},{"s":83,"a":11,"key":"83:11","ar":"ٱلَّذِينَ يُكَذِّبُونَ بِيَوْمِ ٱلدِّينِ","en":"Who deny the Day of Recompense.","tr":"Allatheena yukaththiboonabiyawmi addeen","juz":30,"page":588},{"s":83,"a":12,"key":"83:12","ar":"وَمَا يُكَذِّبُ بِهِۦٓ إِلَّا كُلُّ مُعْتَدٍ أَثِيمٍ","en":"And none deny it except every sinful transgressor.","tr":"Wama yukaththibu bihi illakullu muAAtadin atheem","juz":30,"page":588},{"s":83,"a":13,"key":"83:13","ar":"إِذَا تُتْلَىٰ عَلَيْهِ ءَايَـٰتُنَا قَالَ أَسَـٰطِيرُ ٱلْأَوَّلِينَ","en":"When Our verses are recited to him, he says, \"Legends of the former peoples.\"","tr":"Itha tutla AAalayhi ayatunaqala asateeru al-awwaleen","juz":30,"page":588},{"s":83,"a":14,"key":"83:14","ar":"كَلَّا ۖ بَلْ ۜ رَانَ عَلَىٰ قُلُوبِهِم مَّا كَانُوا۟ يَكْسِبُونَ","en":"No! Rather, the stain has covered their hearts of that which they were earning.1","tr":"Kalla bal rana AAalaquloobihim ma kanoo yaksiboon","juz":30,"page":588},{"s":83,"a":15,"key":"83:15","ar":"كَلَّآ إِنَّهُمْ عَن رَّبِّهِمْ يَوْمَئِذٍ لَّمَحْجُوبُونَ","en":"No! Indeed, from their Lord, that Day, they will be partitioned.1","tr":"Kalla innahum AAan rabbihim yawma-ithinlamahjooboon","juz":30,"page":588},{"s":83,"a":16,"key":"83:16","ar":"ثُمَّ إِنَّهُمْ لَصَالُوا۟ ٱلْجَحِيمِ","en":"Then indeed, they will [enter and] burn in Hellfire.","tr":"Thumma innahum lasaloo aljaheem","juz":30,"page":588},{"s":83,"a":17,"key":"83:17","ar":"ثُمَّ يُقَالُ هَـٰذَا ٱلَّذِى كُنتُم بِهِۦ تُكَذِّبُونَ","en":"Then it will be said [to them], \"This is what you used to deny.\"","tr":"Thumma yuqalu hatha allatheekuntum bihi tukaththiboon","juz":30,"page":588},{"s":83,"a":18,"key":"83:18","ar":"كَلَّآ إِنَّ كِتَـٰبَ ٱلْأَبْرَارِ لَفِى عِلِّيِّينَ","en":"No! Indeed, the record of the righteous is in ʿilliyyūn.","tr":"Kalla inna kitaba al-abrarilafee AAilliyyeen","juz":30,"page":588},{"s":83,"a":19,"key":"83:19","ar":"وَمَآ أَدْرَىٰكَ مَا عِلِّيُّونَ","en":"And what can make you know what is ʿilliyyūn?","tr":"Wama adraka maAAilliyyoon","juz":30,"page":588},{"s":83,"a":20,"key":"83:20","ar":"كِتَـٰبٌ مَّرْقُومٌ","en":"It is [their destination1 recorded in] a register inscribed","tr":"Kitabun marqoom","juz":30,"page":588},{"s":83,"a":21,"key":"83:21","ar":"يَشْهَدُهُ ٱلْمُقَرَّبُونَ","en":"Which is witnessed by those brought near [to Allāh].","tr":"Yashhaduhu almuqarraboon","juz":30,"page":588},{"s":83,"a":22,"key":"83:22","ar":"إِنَّ ٱلْأَبْرَارَ لَفِى نَعِيمٍ","en":"Indeed, the righteous will be in pleasure","tr":"Inna al-abrara lafee naAAeem","juz":30,"page":588},{"s":83,"a":23,"key":"83:23","ar":"عَلَى ٱلْأَرَآئِكِ يَنظُرُونَ","en":"On adorned couches, observing.","tr":"AAala al-ara-iki yanthuroon","juz":30,"page":588},{"s":83,"a":24,"key":"83:24","ar":"تَعْرِفُ فِى وُجُوهِهِمْ نَضْرَةَ ٱلنَّعِيمِ","en":"You will recognize in their faces the radiance of pleasure.","tr":"TaAArifu fee wujoohihim nadrata annaAAeem","juz":30,"page":588},{"s":83,"a":25,"key":"83:25","ar":"يُسْقَوْنَ مِن رَّحِيقٍ مَّخْتُومٍ","en":"They will be given to drink [pure] wine1 [which was] sealed.","tr":"Yusqawna min raheeqin makhtoom","juz":30,"page":588},{"s":83,"a":26,"key":"83:26","ar":"خِتَـٰمُهُۥ مِسْكٌ ۚ وَفِى ذَٰلِكَ فَلْيَتَنَافَسِ ٱلْمُتَنَـٰفِسُونَ","en":"The last of it1 is musk. So for this let the competitors compete.","tr":"Khitamuhu miskun wafee thalikafalyatanafasi almutanafisoon","juz":30,"page":588},{"s":83,"a":27,"key":"83:27","ar":"وَمِزَاجُهُۥ مِن تَسْنِيمٍ","en":"And its mixture is of Tasneem,1","tr":"Wamizajuhu min tasneem","juz":30,"page":588},{"s":83,"a":28,"key":"83:28","ar":"عَيْنًا يَشْرَبُ بِهَا ٱلْمُقَرَّبُونَ","en":"A spring from which those near [to Allāh] drink.","tr":"AAaynan yashrabu biha almuqarraboon","juz":30,"page":588},{"s":83,"a":29,"key":"83:29","ar":"إِنَّ ٱلَّذِينَ أَجْرَمُوا۟ كَانُوا۟ مِنَ ٱلَّذِينَ ءَامَنُوا۟ يَضْحَكُونَ","en":"Indeed, those who committed crimes used to laugh at those who believed.","tr":"Inna allatheena ajramoo kanoomina allatheena amanoo yadhakoon","juz":30,"page":588},{"s":83,"a":30,"key":"83:30","ar":"وَإِذَا مَرُّوا۟ بِهِمْ يَتَغَامَزُونَ","en":"And when they passed by them, they would exchange derisive glances.","tr":"Wa-itha marroo bihim yataghamazoon","juz":30,"page":588},{"s":83,"a":31,"key":"83:31","ar":"وَإِذَا ٱنقَلَبُوٓا۟ إِلَىٰٓ أَهْلِهِمُ ٱنقَلَبُوا۟ فَكِهِينَ","en":"And when they returned to their people, they would return jesting.","tr":"Wa-itha inqalaboo ila ahlihimuinqalaboo fakiheen","juz":30,"page":588},{"s":83,"a":32,"key":"83:32","ar":"وَإِذَا رَأَوْهُمْ قَالُوٓا۟ إِنَّ هَـٰٓؤُلَآءِ لَضَآلُّونَ","en":"And when they saw them, they would say, \"Indeed, those are truly lost.\"","tr":"Wa-itha raawhum qaloo inna haola-iladalloon","juz":30,"page":588},{"s":83,"a":33,"key":"83:33","ar":"وَمَآ أُرْسِلُوا۟ عَلَيْهِمْ حَـٰفِظِينَ","en":"But they had not been sent as guardians over them.","tr":"Wama orsiloo AAalayhim hafitheen","juz":30,"page":588},{"s":83,"a":34,"key":"83:34","ar":"فَٱلْيَوْمَ ٱلَّذِينَ ءَامَنُوا۟ مِنَ ٱلْكُفَّارِ يَضْحَكُونَ","en":"So Today1 those who believed are laughing at the disbelievers,","tr":"Falyawma allatheena amanoomina alkuffari yadhakoon","juz":30,"page":588},{"s":83,"a":35,"key":"83:35","ar":"عَلَى ٱلْأَرَآئِكِ يَنظُرُونَ","en":"On adorned couches, observing.","tr":"AAala al-ara-iki yanthuroon","juz":30,"page":589},{"s":83,"a":36,"key":"83:36","ar":"هَلْ ثُوِّبَ ٱلْكُفَّارُ مَا كَانُوا۟ يَفْعَلُونَ","en":"Have the disbelievers [not] been rewarded [this Day] for what they used to do?","tr":"Hal thuwwiba alkuffaru ma kanooyafAAaloon","juz":30,"page":589},{"s":84,"a":1,"key":"84:1","ar":" إِذَا ٱلسَّمَآءُ ٱنشَقَّتْ","en":"When the sky has split [open]","tr":"Itha assamao inshaqqat","juz":30,"page":589},{"s":84,"a":2,"key":"84:2","ar":"وَأَذِنَتْ لِرَبِّهَا وَحُقَّتْ","en":"And has listened [i.e., responded]1 to its Lord and was obligated [to do so]","tr":"Waathinat lirabbiha wahuqqat","juz":30,"page":589},{"s":84,"a":3,"key":"84:3","ar":"وَإِذَا ٱلْأَرْضُ مُدَّتْ","en":"And when the earth has been extended1","tr":"Wa-itha al-ardu muddat","juz":30,"page":589},{"s":84,"a":4,"key":"84:4","ar":"وَأَلْقَتْ مَا فِيهَا وَتَخَلَّتْ","en":"And has cast out that within it1 and relinquished [it].","tr":"Waalqat ma feeha watakhallat","juz":30,"page":589},{"s":84,"a":5,"key":"84:5","ar":"وَأَذِنَتْ لِرَبِّهَا وَحُقَّتْ","en":"And has listened [i.e., responded] to its Lord and was obligated [to do so] -","tr":"Waathinat lirabbiha wahuqqat","juz":30,"page":589},{"s":84,"a":6,"key":"84:6","ar":"يَـٰٓأَيُّهَا ٱلْإِنسَـٰنُ إِنَّكَ كَادِحٌ إِلَىٰ رَبِّكَ كَدْحًا فَمُلَـٰقِيهِ","en":"O mankind, indeed you are laboring toward your Lord with [great] exertion1 and will meet it.2","tr":"Ya ayyuha al-insanuinnaka kadihun ila rabbika kadhanfamulaqeeh","juz":30,"page":589},{"s":84,"a":7,"key":"84:7","ar":"فَأَمَّا مَنْ أُوتِىَ كِتَـٰبَهُۥ بِيَمِينِهِۦ","en":"Then as for he who is given his record in his right hand,","tr":"Faama man ootiya kitabahubiyameenih","juz":30,"page":589},{"s":84,"a":8,"key":"84:8","ar":"فَسَوْفَ يُحَاسَبُ حِسَابًا يَسِيرًا","en":"He will be judged with an easy account","tr":"Fasawfa yuhasabu hisabanyaseera","juz":30,"page":589},{"s":84,"a":9,"key":"84:9","ar":"وَيَنقَلِبُ إِلَىٰٓ أَهْلِهِۦ مَسْرُورًا","en":"And return to his people in happiness.","tr":"Wayanqalibu ila ahlihi masroora","juz":30,"page":589},{"s":84,"a":10,"key":"84:10","ar":"وَأَمَّا مَنْ أُوتِىَ كِتَـٰبَهُۥ وَرَآءَ ظَهْرِهِۦ","en":"But as for he who is given his record behind his back,","tr":"Waamma man ootiya kitabahu waraathahrih","juz":30,"page":589},{"s":84,"a":11,"key":"84:11","ar":"فَسَوْفَ يَدْعُوا۟ ثُبُورًا","en":"He will cry out for destruction","tr":"Fasawfa yadAAoo thuboora","juz":30,"page":589},{"s":84,"a":12,"key":"84:12","ar":"وَيَصْلَىٰ سَعِيرًا","en":"And [enter to] burn in a Blaze.","tr":"Wayasla saAAeera","juz":30,"page":589},{"s":84,"a":13,"key":"84:13","ar":"إِنَّهُۥ كَانَ فِىٓ أَهْلِهِۦ مَسْرُورًا","en":"Indeed, he had [once] been among his people in happiness;","tr":"Innahu kana fee ahlihi masroora","juz":30,"page":589},{"s":84,"a":14,"key":"84:14","ar":"إِنَّهُۥ ظَنَّ أَن لَّن يَحُورَ","en":"Indeed, he had thought he would never return [to Allāh].","tr":"Innahu thanna an lan yahoor","juz":30,"page":589},{"s":84,"a":15,"key":"84:15","ar":"بَلَىٰٓ إِنَّ رَبَّهُۥ كَانَ بِهِۦ بَصِيرًا","en":"But yes! Indeed, his Lord was ever, of him, Seeing.","tr":"Bala inna rabbahu kana bihi baseera","juz":30,"page":589},{"s":84,"a":16,"key":"84:16","ar":"فَلَآ أُقْسِمُ بِٱلشَّفَقِ","en":"So I swear by the twilight glow","tr":"Fala oqsimu bishshafaq","juz":30,"page":589},{"s":84,"a":17,"key":"84:17","ar":"وَٱلَّيْلِ وَمَا وَسَقَ","en":"And [by] the night and what it envelops","tr":"Wallayli wama wasaq","juz":30,"page":589},{"s":84,"a":18,"key":"84:18","ar":"وَٱلْقَمَرِ إِذَا ٱتَّسَقَ","en":"And [by] the moon when it becomes full","tr":"Walqamari itha ittasaq","juz":30,"page":589},{"s":84,"a":19,"key":"84:19","ar":"لَتَرْكَبُنَّ طَبَقًا عَن طَبَقٍ","en":"[That] you will surely embark upon [i.e., experience] state after state.1","tr":"Latarkabunna tabaqan AAan tabaq","juz":30,"page":589},{"s":84,"a":20,"key":"84:20","ar":"فَمَا لَهُمْ لَا يُؤْمِنُونَ","en":"So what is [the matter] with them [that] they do not believe,","tr":"Fama lahum la yu/minoon","juz":30,"page":589},{"s":84,"a":21,"key":"84:21","ar":"وَإِذَا قُرِئَ عَلَيْهِمُ ٱلْقُرْءَانُ لَا يَسْجُدُونَ ۩","en":"And when the Qur’ān is recited to them, they do not prostrate [to Allāh]?","tr":"Wa-itha quri-a AAalayhimu alqur-anula yasjudoon","juz":30,"page":589},{"s":84,"a":22,"key":"84:22","ar":"بَلِ ٱلَّذِينَ كَفَرُوا۟ يُكَذِّبُونَ","en":"But those who have disbelieved deny,","tr":"Bali allatheena kafaroo yukaththiboon","juz":30,"page":589},{"s":84,"a":23,"key":"84:23","ar":"وَٱللَّهُ أَعْلَمُ بِمَا يُوعُونَ","en":"And Allāh is most knowing of what they keep within themselves.","tr":"Wallahu aAAlamu bimayooAAoon","juz":30,"page":589},{"s":84,"a":24,"key":"84:24","ar":"فَبَشِّرْهُم بِعَذَابٍ أَلِيمٍ","en":"So give them tidings of a painful punishment,","tr":"Fabashshirhum biAAathabin aleem","juz":30,"page":589},{"s":84,"a":25,"key":"84:25","ar":"إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَهُمْ أَجْرٌ غَيْرُ مَمْنُونٍۭ","en":"Except for those who believe and do righteous deeds. For them is a reward uninterrupted.","tr":"Illa allatheena amanoowaAAamiloo assalihati lahum ajrun ghayrumamnoon","juz":30,"page":589},{"s":85,"a":1,"key":"85:1","ar":" وَٱلسَّمَآءِ ذَاتِ ٱلْبُرُوجِ","en":"By the sky containing great stars","tr":"Wassama-i thatialburooj","juz":30,"page":590},{"s":85,"a":2,"key":"85:2","ar":"وَٱلْيَوْمِ ٱلْمَوْعُودِ","en":"And [by] the promised Day","tr":"Walyawmi almawAAood","juz":30,"page":590},{"s":85,"a":3,"key":"85:3","ar":"وَشَاهِدٍ وَمَشْهُودٍ","en":"And [by] the witness and what is witnessed,","tr":"Washahidin wamashhood","juz":30,"page":590},{"s":85,"a":4,"key":"85:4","ar":"قُتِلَ أَصْحَـٰبُ ٱلْأُخْدُودِ","en":"Destroyed [i.e., cursed] were the companions of the trench1","tr":"Qutila as-habu alukhdood","juz":30,"page":590},{"s":85,"a":5,"key":"85:5","ar":"ٱلنَّارِ ذَاتِ ٱلْوَقُودِ","en":"[Containing] the fire full of fuel,","tr":"Annari thati alwaqood","juz":30,"page":590},{"s":85,"a":6,"key":"85:6","ar":"إِذْ هُمْ عَلَيْهَا قُعُودٌ","en":"When they were sitting near it.","tr":"Ith hum AAalayha quAAood","juz":30,"page":590},{"s":85,"a":7,"key":"85:7","ar":"وَهُمْ عَلَىٰ مَا يَفْعَلُونَ بِٱلْمُؤْمِنِينَ شُهُودٌ","en":"And they, to what they were doing against the believers, were witnesses. 1","tr":"Wahum AAala ma yafAAaloona bilmu/mineenashuhood","juz":30,"page":590},{"s":85,"a":8,"key":"85:8","ar":"وَمَا نَقَمُوا۟ مِنْهُمْ إِلَّآ أَن يُؤْمِنُوا۟ بِٱللَّهِ ٱلْعَزِيزِ ٱلْحَمِيدِ","en":"And they resented them not except because they believed in Allāh, the Exalted in Might, the Praiseworthy,","tr":"Wama naqamoo minhum illa anyu/minoo billahi alAAazeezi alhameed","juz":30,"page":590},{"s":85,"a":9,"key":"85:9","ar":"ٱلَّذِى لَهُۥ مُلْكُ ٱلسَّمَـٰوَٰتِ وَٱلْأَرْضِ ۚ وَٱللَّهُ عَلَىٰ كُلِّ شَىْءٍ شَهِيدٌ","en":"To whom belongs the dominion of the heavens and the earth. And Allāh, over all things, is Witness.1","tr":"Allathee lahu mulku assamawatiwal-ardi wallahu AAala kullishay-in shaheed","juz":30,"page":590},{"s":85,"a":10,"key":"85:10","ar":"إِنَّ ٱلَّذِينَ فَتَنُوا۟ ٱلْمُؤْمِنِينَ وَٱلْمُؤْمِنَـٰتِ ثُمَّ لَمْ يَتُوبُوا۟ فَلَهُمْ عَذَابُ جَهَنَّمَ وَلَهُمْ عَذَابُ ٱلْحَرِيقِ","en":"Indeed, those who have tortured1 the believing men and believing women and then have not repented will have the punishment of Hell, and they will have the punishment of the Burning Fire.","tr":"Inna allatheena fatanoo almu/mineenawalmu/minati thumma lam yatooboo falahum AAathabujahannama walahum AAathabu alhareeq","juz":30,"page":590},{"s":85,"a":11,"key":"85:11","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ لَهُمْ جَنَّـٰتٌ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ ۚ ذَٰلِكَ ٱلْفَوْزُ ٱلْكَبِيرُ","en":"Indeed, those who have believed and done righteous deeds will have gardens beneath which rivers flow. That is the great attainment.","tr":"Inna allatheena amanoowaAAamiloo assalihati lahum jannatuntajree min tahtiha al-anharu thalikaalfawzu alkabeer","juz":30,"page":590},{"s":85,"a":12,"key":"85:12","ar":"إِنَّ بَطْشَ رَبِّكَ لَشَدِيدٌ","en":"Indeed, the assault [i.e., vengeance] of your Lord is severe.","tr":"Inna batsha rabbika lashadeed","juz":30,"page":590},{"s":85,"a":13,"key":"85:13","ar":"إِنَّهُۥ هُوَ يُبْدِئُ وَيُعِيدُ","en":"Indeed, it is He who originates [creation] and repeats.","tr":"Innahu huwa yubdi-o wayuAAeed","juz":30,"page":590},{"s":85,"a":14,"key":"85:14","ar":"وَهُوَ ٱلْغَفُورُ ٱلْوَدُودُ","en":"And He is the Forgiving, the Affectionate,","tr":"Wahuwa alghafooru alwadood","juz":30,"page":590},{"s":85,"a":15,"key":"85:15","ar":"ذُو ٱلْعَرْشِ ٱلْمَجِيدُ","en":"Honorable Owner of the Throne,","tr":"Thoo alAAarshi almajeed","juz":30,"page":590},{"s":85,"a":16,"key":"85:16","ar":"فَعَّالٌ لِّمَا يُرِيدُ","en":"Effecter of what He intends.","tr":"FaAAAAalun lima yureed","juz":30,"page":590},{"s":85,"a":17,"key":"85:17","ar":"هَلْ أَتَىٰكَ حَدِيثُ ٱلْجُنُودِ","en":"Has there reached you the story of the soldiers -","tr":"Hal ataka hadeethu aljunood","juz":30,"page":590},{"s":85,"a":18,"key":"85:18","ar":"فِرْعَوْنَ وَثَمُودَ","en":"[Those of] Pharaoh and Thamūd?","tr":"FirAAawna wathamood","juz":30,"page":590},{"s":85,"a":19,"key":"85:19","ar":"بَلِ ٱلَّذِينَ كَفَرُوا۟ فِى تَكْذِيبٍ","en":"But they who disbelieve are in [persistent] denial,","tr":"Bali allatheena kafaroo fee taktheeb","juz":30,"page":590},{"s":85,"a":20,"key":"85:20","ar":"وَٱللَّهُ مِن وَرَآئِهِم مُّحِيطٌۢ","en":"While Allāh encompasses them from behind.1","tr":"Wallahu min wara-ihimmuheet","juz":30,"page":590},{"s":85,"a":21,"key":"85:21","ar":"بَلْ هُوَ قُرْءَانٌ مَّجِيدٌ","en":"But this is an honored Qur’ān","tr":"Bal huwa qur-anun majeed","juz":30,"page":590},{"s":85,"a":22,"key":"85:22","ar":"فِى لَوْحٍ مَّحْفُوظٍۭ","en":"[Inscribed] in a Preserved Slate.","tr":"Fee lawhin mahfooth","juz":30,"page":590},{"s":86,"a":1,"key":"86:1","ar":" وَٱلسَّمَآءِ وَٱلطَّارِقِ","en":"By the sky and the night comer","tr":"Wassama-i wattariq","juz":30,"page":591},{"s":86,"a":2,"key":"86:2","ar":"وَمَآ أَدْرَىٰكَ مَا ٱلطَّارِقُ","en":"And what can make you know what is the night comer?","tr":"Wama adraka ma attariq","juz":30,"page":591},{"s":86,"a":3,"key":"86:3","ar":"ٱلنَّجْمُ ٱلثَّاقِبُ","en":"It is the piercing star1","tr":"Annajmu aththaqib","juz":30,"page":591},{"s":86,"a":4,"key":"86:4","ar":"إِن كُلُّ نَفْسٍ لَّمَّا عَلَيْهَا حَافِظٌ","en":"There is no soul but that it has over it a protector.","tr":"In kullu nafsin lamma AAalayha hafith","juz":30,"page":591},{"s":86,"a":5,"key":"86:5","ar":"فَلْيَنظُرِ ٱلْإِنسَـٰنُ مِمَّ خُلِقَ","en":"So let man observe from what he was created.","tr":"Falyanthuri al-insanumimma khuliq","juz":30,"page":591},{"s":86,"a":6,"key":"86:6","ar":"خُلِقَ مِن مَّآءٍ دَافِقٍ","en":"He was created from a fluid, ejected,","tr":"Khuliqa min ma-in dafiq","juz":30,"page":591},{"s":86,"a":7,"key":"86:7","ar":"يَخْرُجُ مِنۢ بَيْنِ ٱلصُّلْبِ وَٱلتَّرَآئِبِ","en":"Emerging from between the backbone and the ribs.","tr":"Yakhruju min bayni assulbi wattara-ib","juz":30,"page":591},{"s":86,"a":8,"key":"86:8","ar":"إِنَّهُۥ عَلَىٰ رَجْعِهِۦ لَقَادِرٌ","en":"Indeed, He [i.e., Allāh], to return him [to life], is Able.","tr":"Innahu AAala rajAAihi laqadir","juz":30,"page":591},{"s":86,"a":9,"key":"86:9","ar":"يَوْمَ تُبْلَى ٱلسَّرَآئِرُ","en":"The Day when secrets will be put on trial,1","tr":"Yawma tubla assara-ir","juz":30,"page":591},{"s":86,"a":10,"key":"86:10","ar":"فَمَا لَهُۥ مِن قُوَّةٍ وَلَا نَاصِرٍ","en":"Then he [i.e., man] will have no power or any helper.","tr":"Fama lahu min quwwatin wala nasir","juz":30,"page":591},{"s":86,"a":11,"key":"86:11","ar":"وَٱلسَّمَآءِ ذَاتِ ٱلرَّجْعِ","en":"By the sky which sends back1","tr":"Wassama-i thati arrajAA","juz":30,"page":591},{"s":86,"a":12,"key":"86:12","ar":"وَٱلْأَرْضِ ذَاتِ ٱلصَّدْعِ","en":"And [by] the earth which splits,1","tr":"Wal-ardi thati assadAA","juz":30,"page":591},{"s":86,"a":13,"key":"86:13","ar":"إِنَّهُۥ لَقَوْلٌ فَصْلٌ","en":"Indeed, it [i.e., the Qur’ān] is a decisive statement,","tr":"Innahu laqawlun fasl","juz":30,"page":591},{"s":86,"a":14,"key":"86:14","ar":"وَمَا هُوَ بِٱلْهَزْلِ","en":"And it is not amusement.","tr":"Wama huwa bilhazl","juz":30,"page":591},{"s":86,"a":15,"key":"86:15","ar":"إِنَّهُمْ يَكِيدُونَ كَيْدًا","en":"Indeed, they are planning a plan,","tr":"Innahum yakeedoona kayda","juz":30,"page":591},{"s":86,"a":16,"key":"86:16","ar":"وَأَكِيدُ كَيْدًا","en":"But I am planning a plan.","tr":"Waakeedu kayda","juz":30,"page":591},{"s":86,"a":17,"key":"86:17","ar":"فَمَهِّلِ ٱلْكَـٰفِرِينَ أَمْهِلْهُمْ رُوَيْدًۢا","en":"So allow time for the disbelievers. Leave them awhile.1","tr":"Famahhili alkafireena amhilhum ruwayda","juz":30,"page":591},{"s":87,"a":1,"key":"87:1","ar":" سَبِّحِ ٱسْمَ رَبِّكَ ٱلْأَعْلَى","en":"Exalt the name of your Lord, the Most High,","tr":"Sabbihi isma rabbika al-aAAla","juz":30,"page":591},{"s":87,"a":2,"key":"87:2","ar":"ٱلَّذِى خَلَقَ فَسَوَّىٰ","en":"Who created and proportioned","tr":"Allathee khalaqa fasawwa","juz":30,"page":591},{"s":87,"a":3,"key":"87:3","ar":"وَٱلَّذِى قَدَّرَ فَهَدَىٰ","en":"And who destined and [then] guided","tr":"Wallathee qaddara fahada","juz":30,"page":591},{"s":87,"a":4,"key":"87:4","ar":"وَٱلَّذِىٓ أَخْرَجَ ٱلْمَرْعَىٰ","en":"And who brings out the pasture","tr":"Wallathee akhraja almarAAa","juz":30,"page":591},{"s":87,"a":5,"key":"87:5","ar":"فَجَعَلَهُۥ غُثَآءً أَحْوَىٰ","en":"And [then] makes it black stubble.","tr":"FajaAAalahu ghuthaan ahwa","juz":30,"page":591},{"s":87,"a":6,"key":"87:6","ar":"سَنُقْرِئُكَ فَلَا تَنسَىٰٓ","en":"We will make you recite, [O Muḥammad], and you will not forget,","tr":"Sanuqri-oka fala tansa","juz":30,"page":591},{"s":87,"a":7,"key":"87:7","ar":"إِلَّا مَا شَآءَ ٱللَّهُ ۚ إِنَّهُۥ يَعْلَمُ ٱلْجَهْرَ وَمَا يَخْفَىٰ","en":"Except what Allāh should will. Indeed, He knows what is declared and what is hidden.","tr":"Illa ma shaa Allahuinnahu yaAAlamu aljahra wama yakhfa","juz":30,"page":591},{"s":87,"a":8,"key":"87:8","ar":"وَنُيَسِّرُكَ لِلْيُسْرَىٰ","en":"And We will ease you toward ease.1","tr":"Wanuyassiruka lilyusra","juz":30,"page":591},{"s":87,"a":9,"key":"87:9","ar":"فَذَكِّرْ إِن نَّفَعَتِ ٱلذِّكْرَىٰ","en":"So remind, if the reminder should benefit;1","tr":"Fathakkir in nafaAAati aththikra","juz":30,"page":591},{"s":87,"a":10,"key":"87:10","ar":"سَيَذَّكَّرُ مَن يَخْشَىٰ","en":"He who fears [Allāh] will be reminded.","tr":"Sayaththakkaru man yakhsha","juz":30,"page":591},{"s":87,"a":11,"key":"87:11","ar":"وَيَتَجَنَّبُهَا ٱلْأَشْقَى","en":"But the wretched one will avoid it","tr":"Wayatajannabuha al-ashqa","juz":30,"page":591},{"s":87,"a":12,"key":"87:12","ar":"ٱلَّذِى يَصْلَى ٱلنَّارَ ٱلْكُبْرَىٰ","en":"[He] who will [enter and] burn in the greatest Fire,","tr":"Allathee yasla annaraalkubra","juz":30,"page":591},{"s":87,"a":13,"key":"87:13","ar":"ثُمَّ لَا يَمُوتُ فِيهَا وَلَا يَحْيَىٰ","en":"Neither dying therein nor living.","tr":"Thumma la yamootu feeha walayahya","juz":30,"page":591},{"s":87,"a":14,"key":"87:14","ar":"قَدْ أَفْلَحَ مَن تَزَكَّىٰ","en":"He has certainly succeeded who purifies himself","tr":"Qad aflaha man tazakka","juz":30,"page":591},{"s":87,"a":15,"key":"87:15","ar":"وَذَكَرَ ٱسْمَ رَبِّهِۦ فَصَلَّىٰ","en":"And mentions the name of his Lord and prays.","tr":"Wathakara isma rabbihi fasalla","juz":30,"page":591},{"s":87,"a":16,"key":"87:16","ar":"بَلْ تُؤْثِرُونَ ٱلْحَيَوٰةَ ٱلدُّنْيَا","en":"But you prefer the worldly life,","tr":"Bal tu/thiroona alhayata addunya","juz":30,"page":592},{"s":87,"a":17,"key":"87:17","ar":"وَٱلْـَٔاخِرَةُ خَيْرٌ وَأَبْقَىٰٓ","en":"While the Hereafter is better and more enduring.","tr":"Wal-akhiratu khayrun waabqa","juz":30,"page":592},{"s":87,"a":18,"key":"87:18","ar":"إِنَّ هَـٰذَا لَفِى ٱلصُّحُفِ ٱلْأُولَىٰ","en":"Indeed, this is in the former scriptures,","tr":"Inna hatha lafee assuhufial-oola","juz":30,"page":592},{"s":87,"a":19,"key":"87:19","ar":"صُحُفِ إِبْرَٰهِيمَ وَمُوسَىٰ","en":"The scriptures of Abraham and Moses.","tr":"Suhufi ibraheema wamoosa","juz":30,"page":592},{"s":88,"a":1,"key":"88:1","ar":" هَلْ أَتَىٰكَ حَدِيثُ ٱلْغَـٰشِيَةِ","en":"Has there reached you the report of the Overwhelming [event]?","tr":"Hal ataka hadeethu alghashiyat","juz":30,"page":592},{"s":88,"a":2,"key":"88:2","ar":"وُجُوهٌ يَوْمَئِذٍ خَـٰشِعَةٌ","en":"[Some] faces, that Day, will be humbled,","tr":"Wujoohun yawma-ithin khashiAAa","juz":30,"page":592},{"s":88,"a":3,"key":"88:3","ar":"عَامِلَةٌ نَّاصِبَةٌ","en":"Working [hard] and exhausted.1","tr":"AAamilatun nasiba","juz":30,"page":592},{"s":88,"a":4,"key":"88:4","ar":"تَصْلَىٰ نَارًا حَامِيَةً","en":"They will [enter to] burn in an intensely hot Fire.","tr":"Tasla naran hamiya","juz":30,"page":592},{"s":88,"a":5,"key":"88:5","ar":"تُسْقَىٰ مِنْ عَيْنٍ ءَانِيَةٍ","en":"They will be given drink from a boiling spring.","tr":"Tusqa min AAaynin aniya","juz":30,"page":592},{"s":88,"a":6,"key":"88:6","ar":"لَّيْسَ لَهُمْ طَعَامٌ إِلَّا مِن ضَرِيعٍ","en":"For them there will be no food except from a poisonous, thorny plant","tr":"Laysa lahum taAAamun illamin dareeAA","juz":30,"page":592},{"s":88,"a":7,"key":"88:7","ar":"لَّا يُسْمِنُ وَلَا يُغْنِى مِن جُوعٍ","en":"Which neither nourishes nor avails against hunger.","tr":"La yusminu wala yughnee minjooAA","juz":30,"page":592},{"s":88,"a":8,"key":"88:8","ar":"وُجُوهٌ يَوْمَئِذٍ نَّاعِمَةٌ","en":"[Other] faces, that Day, will show pleasure.","tr":"Wujoohun yawma-ithin naAAima","juz":30,"page":592},{"s":88,"a":9,"key":"88:9","ar":"لِّسَعْيِهَا رَاضِيَةٌ","en":"With their effort [they are] satisfied","tr":"LisaAAyiha radiya","juz":30,"page":592},{"s":88,"a":10,"key":"88:10","ar":"فِى جَنَّةٍ عَالِيَةٍ","en":"In an elevated garden,","tr":"Fee jannatin AAaliya","juz":30,"page":592},{"s":88,"a":11,"key":"88:11","ar":"لَّا تَسْمَعُ فِيهَا لَـٰغِيَةً","en":"Wherein they will hear no unsuitable speech.1","tr":"La tasmaAAu feeha laghiya","juz":30,"page":592},{"s":88,"a":12,"key":"88:12","ar":"فِيهَا عَيْنٌ جَارِيَةٌ","en":"Within it is a flowing spring.","tr":"Feeha AAaynun jariya","juz":30,"page":592},{"s":88,"a":13,"key":"88:13","ar":"فِيهَا سُرُرٌ مَّرْفُوعَةٌ","en":"Within it are couches raised high","tr":"Feeha sururun marfooAAa","juz":30,"page":592},{"s":88,"a":14,"key":"88:14","ar":"وَأَكْوَابٌ مَّوْضُوعَةٌ","en":"And cups put in place","tr":"Waakwabun mawdooAAa","juz":30,"page":592},{"s":88,"a":15,"key":"88:15","ar":"وَنَمَارِقُ مَصْفُوفَةٌ","en":"And cushions lined up","tr":"Wanamariqu masfoofa","juz":30,"page":592},{"s":88,"a":16,"key":"88:16","ar":"وَزَرَابِىُّ مَبْثُوثَةٌ","en":"And carpets spread around.","tr":"Wazarabiyyu mabthootha","juz":30,"page":592},{"s":88,"a":17,"key":"88:17","ar":"أَفَلَا يَنظُرُونَ إِلَى ٱلْإِبِلِ كَيْفَ خُلِقَتْ","en":"Then do they not look at the camels - how they are created?","tr":"Afala yanthuroona ilaal-ibili kayfa khuliqat","juz":30,"page":592},{"s":88,"a":18,"key":"88:18","ar":"وَإِلَى ٱلسَّمَآءِ كَيْفَ رُفِعَتْ","en":"And at the sky - how it is raised?","tr":"Wa-ila assama-i kayfarufiAAat","juz":30,"page":592},{"s":88,"a":19,"key":"88:19","ar":"وَإِلَى ٱلْجِبَالِ كَيْفَ نُصِبَتْ","en":"And at the mountains - how they are erected?","tr":"Wa-ila aljibali kayfa nusibat","juz":30,"page":592},{"s":88,"a":20,"key":"88:20","ar":"وَإِلَى ٱلْأَرْضِ كَيْفَ سُطِحَتْ","en":"And at the earth - how it is spread out?","tr":"Wa-ila al-ardi kayfa sutihat","juz":30,"page":592},{"s":88,"a":21,"key":"88:21","ar":"فَذَكِّرْ إِنَّمَآ أَنتَ مُذَكِّرٌ","en":"So remind, [O Muḥammad]; you are only a reminder.","tr":"Fathakkir innama anta muthakkir","juz":30,"page":592},{"s":88,"a":22,"key":"88:22","ar":"لَّسْتَ عَلَيْهِم بِمُصَيْطِرٍ","en":"You are not over them a controller.","tr":"Lasta AAalayhim bimusaytir","juz":30,"page":592},{"s":88,"a":23,"key":"88:23","ar":"إِلَّا مَن تَوَلَّىٰ وَكَفَرَ","en":"However, he who turns away and disbelieves","tr":"Illa man tawalla wakafar","juz":30,"page":592},{"s":88,"a":24,"key":"88:24","ar":"فَيُعَذِّبُهُ ٱللَّهُ ٱلْعَذَابَ ٱلْأَكْبَرَ","en":"Then Allāh will punish him with the greatest punishment.","tr":"FayuAAaththibuhu Allahu alAAathabaal-akbar","juz":30,"page":592},{"s":88,"a":25,"key":"88:25","ar":"إِنَّ إِلَيْنَآ إِيَابَهُمْ","en":"Indeed, to Us is their return.","tr":"Inna ilayna iyabahum","juz":30,"page":592},{"s":88,"a":26,"key":"88:26","ar":"ثُمَّ إِنَّ عَلَيْنَا حِسَابَهُم","en":"Then indeed, upon Us is their account.","tr":"Thumma inna AAalayna hisabahum","juz":30,"page":592},{"s":89,"a":1,"key":"89:1","ar":" وَٱلْفَجْرِ","en":"By the dawn","tr":"Walfajr","juz":30,"page":593},{"s":89,"a":2,"key":"89:2","ar":"وَلَيَالٍ عَشْرٍ","en":"And [by] ten nights1","tr":"Walayalin AAashr","juz":30,"page":593},{"s":89,"a":3,"key":"89:3","ar":"وَٱلشَّفْعِ وَٱلْوَتْرِ","en":"And [by] the even [number] and the odd","tr":"WashshafAAi walwatr","juz":30,"page":593},{"s":89,"a":4,"key":"89:4","ar":"وَٱلَّيْلِ إِذَا يَسْرِ","en":"And [by] the night when it passes,","tr":"Wallayli itha yasr","juz":30,"page":593},{"s":89,"a":5,"key":"89:5","ar":"هَلْ فِى ذَٰلِكَ قَسَمٌ لِّذِى حِجْرٍ","en":"Is there [not] in [all] that an oath [sufficient] for one of perception?1","tr":"Hal fee thalika qasamun lithee hijr","juz":30,"page":593},{"s":89,"a":6,"key":"89:6","ar":"أَلَمْ تَرَ كَيْفَ فَعَلَ رَبُّكَ بِعَادٍ","en":"Have you not considered how your Lord dealt with ʿAad -","tr":"Alam tara kayfa faAAala rabbuka biAAad","juz":30,"page":593},{"s":89,"a":7,"key":"89:7","ar":"إِرَمَ ذَاتِ ٱلْعِمَادِ","en":"[With] Iram1 - who had lofty pillars,2","tr":"Irama thati alAAimad","juz":30,"page":593},{"s":89,"a":8,"key":"89:8","ar":"ٱلَّتِى لَمْ يُخْلَقْ مِثْلُهَا فِى ٱلْبِلَـٰدِ","en":"The likes of whom had never been created in the land?","tr":"Allatee lam yukhlaq mithluha fee albilad","juz":30,"page":593},{"s":89,"a":9,"key":"89:9","ar":"وَثَمُودَ ٱلَّذِينَ جَابُوا۟ ٱلصَّخْرَ بِٱلْوَادِ","en":"And [with] Thamūd, who carved out the rocks in the valley?","tr":"Wathamooda allatheena jaboo assakhrabilwad","juz":30,"page":593},{"s":89,"a":10,"key":"89:10","ar":"وَفِرْعَوْنَ ذِى ٱلْأَوْتَادِ","en":"And [with] Pharaoh, owner of the stakes?1","tr":"WafirAAawna thee al-awtad","juz":30,"page":593},{"s":89,"a":11,"key":"89:11","ar":"ٱلَّذِينَ طَغَوْا۟ فِى ٱلْبِلَـٰدِ","en":"[All of] whom oppressed within the lands","tr":"Allatheena taghaw fee albilad","juz":30,"page":593},{"s":89,"a":12,"key":"89:12","ar":"فَأَكْثَرُوا۟ فِيهَا ٱلْفَسَادَ","en":"And increased therein the corruption.","tr":"Faaktharoo feeha alfasad","juz":30,"page":593},{"s":89,"a":13,"key":"89:13","ar":"فَصَبَّ عَلَيْهِمْ رَبُّكَ سَوْطَ عَذَابٍ","en":"So your Lord poured upon them a scourge of punishment.","tr":"Fasabba AAalayhim rabbuka sawtaAAathab","juz":30,"page":593},{"s":89,"a":14,"key":"89:14","ar":"إِنَّ رَبَّكَ لَبِٱلْمِرْصَادِ","en":"Indeed, your Lord is in observation.","tr":"Inna rabbaka labilmirsad","juz":30,"page":593},{"s":89,"a":15,"key":"89:15","ar":"فَأَمَّا ٱلْإِنسَـٰنُ إِذَا مَا ٱبْتَلَىٰهُ رَبُّهُۥ فَأَكْرَمَهُۥ وَنَعَّمَهُۥ فَيَقُولُ رَبِّىٓ أَكْرَمَنِ","en":"And as for man, when his Lord tries him and [thus] is generous to him and favors him, he says, \"My Lord has honored me.\"1","tr":"Faamma al-insanu itha maibtalahu rabbuhu faakramahu wanaAAAAamahu fayaqoolu rabbeeakraman","juz":30,"page":593},{"s":89,"a":16,"key":"89:16","ar":"وَأَمَّآ إِذَا مَا ٱبْتَلَىٰهُ فَقَدَرَ عَلَيْهِ رِزْقَهُۥ فَيَقُولُ رَبِّىٓ أَهَـٰنَنِ","en":"But when He tries him and restricts his provision, he says, \"My Lord has humiliated me.\"","tr":"Waamma itha ma ibtalahufaqadara AAalayhi rizqahu fayaqoolu rabbee ahanan","juz":30,"page":593},{"s":89,"a":17,"key":"89:17","ar":"كَلَّا ۖ بَل لَّا تُكْرِمُونَ ٱلْيَتِيمَ","en":"No!1 But you do not honor the orphan","tr":"Kalla bal la tukrimoonaalyateem","juz":30,"page":593},{"s":89,"a":18,"key":"89:18","ar":"وَلَا تَحَـٰٓضُّونَ عَلَىٰ طَعَامِ ٱلْمِسْكِينِ","en":"And you do not encourage one another to feed the poor.","tr":"Wala tahaddoona AAala taAAamialmiskeen","juz":30,"page":593},{"s":89,"a":19,"key":"89:19","ar":"وَتَأْكُلُونَ ٱلتُّرَاثَ أَكْلًا لَّمًّا","en":"And you consume inheritance, devouring [it] altogether,1","tr":"Wata/kuloona atturatha aklanlamma","juz":30,"page":593},{"s":89,"a":20,"key":"89:20","ar":"وَتُحِبُّونَ ٱلْمَالَ حُبًّا جَمًّا","en":"And you love wealth with immense love.","tr":"Watuhibboona almala hubbanjamma","juz":30,"page":593},{"s":89,"a":21,"key":"89:21","ar":"كَلَّآ إِذَا دُكَّتِ ٱلْأَرْضُ دَكًّا دَكًّا","en":"No! When the earth has been leveled - pounded and crushed","tr":"Kalla itha dukkati al-ardudakkan dakka","juz":30,"page":593},{"s":89,"a":22,"key":"89:22","ar":"وَجَآءَ رَبُّكَ وَٱلْمَلَكُ صَفًّا صَفًّا","en":"And your Lord has come1 and the angels, rank upon rank,","tr":"Wajaa rabbuka walmalaku saffansaffa","juz":30,"page":593},{"s":89,"a":23,"key":"89:23","ar":"وَجِا۟ىٓءَ يَوْمَئِذٍۭ بِجَهَنَّمَ ۚ يَوْمَئِذٍ يَتَذَكَّرُ ٱلْإِنسَـٰنُ وَأَنَّىٰ لَهُ ٱلذِّكْرَىٰ","en":"And brought [within view], that Day, is Hell - that Day, man will remember, but how [i.e., what good] to him will be the remembrance?","tr":"Wajee-a yawma-ithin bijahannamayawma-ithin yatathakkaru al-insanu waannalahu aththikra","juz":30,"page":593},{"s":89,"a":24,"key":"89:24","ar":"يَقُولُ يَـٰلَيْتَنِى قَدَّمْتُ لِحَيَاتِى","en":"He will say, \"Oh, I wish I had sent ahead [some good] for my life.\"1","tr":"Yaqoolu ya laytanee qaddamtu lihayatee","juz":30,"page":594},{"s":89,"a":25,"key":"89:25","ar":"فَيَوْمَئِذٍ لَّا يُعَذِّبُ عَذَابَهُۥٓ أَحَدٌ","en":"So on that Day, none will punish [as severely] as His punishment,","tr":"Fayawma-ithin la yuAAaththibuAAathabahu ahad","juz":30,"page":594},{"s":89,"a":26,"key":"89:26","ar":"وَلَا يُوثِقُ وَثَاقَهُۥٓ أَحَدٌ","en":"And none will bind [as severely] as His binding [of the evildoers].","tr":"Wala yoothiqu wathaqahu ahad","juz":30,"page":594},{"s":89,"a":27,"key":"89:27","ar":"يَـٰٓأَيَّتُهَا ٱلنَّفْسُ ٱلْمُطْمَئِنَّةُ","en":"[To the righteous it will be said], \"O reassured soul,","tr":"Ya ayyatuha annafsualmutma-inna","juz":30,"page":594},{"s":89,"a":28,"key":"89:28","ar":"ٱرْجِعِىٓ إِلَىٰ رَبِّكِ رَاضِيَةً مَّرْضِيَّةً","en":"Return to your Lord, well-pleased and pleasing [to Him],","tr":"IrjiAAee ila rabbiki radiyatanmardiyya","juz":30,"page":594},{"s":89,"a":29,"key":"89:29","ar":"فَٱدْخُلِى فِى عِبَـٰدِى","en":"And enter among My [righteous] servants","tr":"Fadkhulee fee AAibadee","juz":30,"page":594},{"s":89,"a":30,"key":"89:30","ar":"وَٱدْخُلِى جَنَّتِى","en":"And enter My Paradise.\"","tr":"Wadkhulee jannatee","juz":30,"page":594},{"s":90,"a":1,"key":"90:1","ar":" لَآ أُقْسِمُ بِهَـٰذَا ٱلْبَلَدِ","en":"I swear by this city [i.e., Makkah]","tr":"La oqsimu bihatha albalad","juz":30,"page":594},{"s":90,"a":2,"key":"90:2","ar":"وَأَنتَ حِلٌّۢ بِهَـٰذَا ٱلْبَلَدِ","en":"And you, [O Muḥammad], are free of restriction in this city","tr":"Waanta hillun bihatha albalad","juz":30,"page":594},{"s":90,"a":3,"key":"90:3","ar":"وَوَالِدٍ وَمَا وَلَدَ","en":"And [by] the father1 and that which was born [of him],","tr":"Wawalidin wama walad","juz":30,"page":594},{"s":90,"a":4,"key":"90:4","ar":"لَقَدْ خَلَقْنَا ٱلْإِنسَـٰنَ فِى كَبَدٍ","en":"We have certainly created man into hardship.","tr":"Laqad khalaqna al-insana feekabad","juz":30,"page":594},{"s":90,"a":5,"key":"90:5","ar":"أَيَحْسَبُ أَن لَّن يَقْدِرَ عَلَيْهِ أَحَدٌ","en":"Does he think that never will anyone overcome him?","tr":"Ayahsabu an lan yaqdira AAalayhi ahad","juz":30,"page":594},{"s":90,"a":6,"key":"90:6","ar":"يَقُولُ أَهْلَكْتُ مَالًا لُّبَدًا","en":"He says, \"I have spent wealth in abundance.\"","tr":"Yaqoolu ahlaktu malan lubada","juz":30,"page":594},{"s":90,"a":7,"key":"90:7","ar":"أَيَحْسَبُ أَن لَّمْ يَرَهُۥٓ أَحَدٌ","en":"Does he think that no one has seen him?","tr":"Ayahsabu an lam yarahu ahad","juz":30,"page":594},{"s":90,"a":8,"key":"90:8","ar":"أَلَمْ نَجْعَل لَّهُۥ عَيْنَيْنِ","en":"Have We not made for him two eyes?","tr":"Alam najAAal lahu AAaynayn","juz":30,"page":594},{"s":90,"a":9,"key":"90:9","ar":"وَلِسَانًا وَشَفَتَيْنِ","en":"And a tongue and two lips?","tr":"Walisanan washafatayn","juz":30,"page":594},{"s":90,"a":10,"key":"90:10","ar":"وَهَدَيْنَـٰهُ ٱلنَّجْدَيْنِ","en":"And have shown him the two ways?1","tr":"Wahadaynahu annajdayn","juz":30,"page":594},{"s":90,"a":11,"key":"90:11","ar":"فَلَا ٱقْتَحَمَ ٱلْعَقَبَةَ","en":"But he has not broken through the difficult pass.1","tr":"Fala iqtahama alAAaqaba","juz":30,"page":594},{"s":90,"a":12,"key":"90:12","ar":"وَمَآ أَدْرَىٰكَ مَا ٱلْعَقَبَةُ","en":"And what can make you know what is [breaking through] the difficult pass?","tr":"Wama adraka maalAAaqaba","juz":30,"page":594},{"s":90,"a":13,"key":"90:13","ar":"فَكُّ رَقَبَةٍ","en":"It is the freeing of a slave","tr":"Fakku raqaba","juz":30,"page":594},{"s":90,"a":14,"key":"90:14","ar":"أَوْ إِطْعَـٰمٌ فِى يَوْمٍ ذِى مَسْغَبَةٍ","en":"Or feeding on a day of severe hunger","tr":"Aw itAAamun fee yawmin theemasghaba","juz":30,"page":594},{"s":90,"a":15,"key":"90:15","ar":"يَتِيمًا ذَا مَقْرَبَةٍ","en":"An orphan of near relationship","tr":"Yateeman tha maqraba","juz":30,"page":594},{"s":90,"a":16,"key":"90:16","ar":"أَوْ مِسْكِينًا ذَا مَتْرَبَةٍ","en":"Or a needy person in misery","tr":"Aw miskeenan tha matraba","juz":30,"page":594},{"s":90,"a":17,"key":"90:17","ar":"ثُمَّ كَانَ مِنَ ٱلَّذِينَ ءَامَنُوا۟ وَتَوَاصَوْا۟ بِٱلصَّبْرِ وَتَوَاصَوْا۟ بِٱلْمَرْحَمَةِ","en":"And then being among those who believed and advised one another to patience and advised one another to compassion.","tr":"Thumma kana mina allatheena amanoowatawasaw bissabri watawasaw bilmarhama","juz":30,"page":594},{"s":90,"a":18,"key":"90:18","ar":"أُو۟لَـٰٓئِكَ أَصْحَـٰبُ ٱلْمَيْمَنَةِ","en":"Those are the companions of the right.1","tr":"Ola-ika as-habualmaymana","juz":30,"page":594},{"s":90,"a":19,"key":"90:19","ar":"وَٱلَّذِينَ كَفَرُوا۟ بِـَٔايَـٰتِنَا هُمْ أَصْحَـٰبُ ٱلْمَشْـَٔمَةِ","en":"But they who disbelieved in Our signs - those are the companions of the left.1","tr":"Wallatheena kafaroo bi-ayatinahum as-habu almash-ama","juz":30,"page":594},{"s":90,"a":20,"key":"90:20","ar":"عَلَيْهِمْ نَارٌ مُّؤْصَدَةٌۢ","en":"Over them will be fire closed in.1","tr":"AAalayhim narun mu/sada","juz":30,"page":594},{"s":91,"a":1,"key":"91:1","ar":" وَٱلشَّمْسِ وَضُحَىٰهَا","en":"By the sun and its brightness","tr":"Washshamsi waduhaha","juz":30,"page":595},{"s":91,"a":2,"key":"91:2","ar":"وَٱلْقَمَرِ إِذَا تَلَىٰهَا","en":"And [by] the moon when it follows it","tr":"Walqamari itha talaha","juz":30,"page":595},{"s":91,"a":3,"key":"91:3","ar":"وَٱلنَّهَارِ إِذَا جَلَّىٰهَا","en":"And [by] the day when it displays it1","tr":"Wannahari itha jallaha","juz":30,"page":595},{"s":91,"a":4,"key":"91:4","ar":"وَٱلَّيْلِ إِذَا يَغْشَىٰهَا","en":"And [by] the night when it covers [i.e., conceals] it","tr":"Wallayli itha yaghshaha","juz":30,"page":595},{"s":91,"a":5,"key":"91:5","ar":"وَٱلسَّمَآءِ وَمَا بَنَىٰهَا","en":"And [by] the sky and He who constructed it","tr":"Wassama-i wama banaha","juz":30,"page":595},{"s":91,"a":6,"key":"91:6","ar":"وَٱلْأَرْضِ وَمَا طَحَىٰهَا","en":"And [by] the earth and He who spread it","tr":"Wal-ardi wama tahaha","juz":30,"page":595},{"s":91,"a":7,"key":"91:7","ar":"وَنَفْسٍ وَمَا سَوَّىٰهَا","en":"And [by] the soul and He who proportioned it1","tr":"Wanafsin wama sawwaha","juz":30,"page":595},{"s":91,"a":8,"key":"91:8","ar":"فَأَلْهَمَهَا فُجُورَهَا وَتَقْوَىٰهَا","en":"And inspired it [with discernment of] its wickedness and its righteousness,","tr":"Faalhamaha fujooraha wataqwaha","juz":30,"page":595},{"s":91,"a":9,"key":"91:9","ar":"قَدْ أَفْلَحَ مَن زَكَّىٰهَا","en":"He has succeeded who purifies it,","tr":"Qad aflaha man zakkaha","juz":30,"page":595},{"s":91,"a":10,"key":"91:10","ar":"وَقَدْ خَابَ مَن دَسَّىٰهَا","en":"And he has failed who instills it [with corruption].","tr":"Waqad khaba man dassaha","juz":30,"page":595},{"s":91,"a":11,"key":"91:11","ar":"كَذَّبَتْ ثَمُودُ بِطَغْوَىٰهَآ","en":"Thamūd denied [their prophet] by reason of their transgression,","tr":"Kaththabat thamoodu bitaghwaha","juz":30,"page":595},{"s":91,"a":12,"key":"91:12","ar":"إِذِ ٱنۢبَعَثَ أَشْقَىٰهَا","en":"When the most wretched of them was sent forth.1","tr":"Ithi inbaAAatha ashqaha","juz":30,"page":595},{"s":91,"a":13,"key":"91:13","ar":"فَقَالَ لَهُمْ رَسُولُ ٱللَّهِ نَاقَةَ ٱللَّهِ وَسُقْيَـٰهَا","en":"And the messenger of Allāh [i.e., Ṣāliḥ] said to them, \"[Do not harm] the she-camel of Allāh or [prevent her from] her drink.\"","tr":"Faqala lahum rasoolu Allahi naqataAllahi wasuqyaha","juz":30,"page":595},{"s":91,"a":14,"key":"91:14","ar":"فَكَذَّبُوهُ فَعَقَرُوهَا فَدَمْدَمَ عَلَيْهِمْ رَبُّهُم بِذَنۢبِهِمْ فَسَوَّىٰهَا","en":"But they denied him and hamstrung1 her. So their Lord brought down upon them destruction for their sin and made it equal [upon all of them].","tr":"Fakaththaboohu faAAaqaroohafadamdama AAalayhim rabbuhum bithanbihim fasawwaha","juz":30,"page":595},{"s":91,"a":15,"key":"91:15","ar":"وَلَا يَخَافُ عُقْبَـٰهَا","en":"And He does not fear the consequence thereof.1","tr":"Wala yakhafu AAuqbaha","juz":30,"page":595},{"s":92,"a":1,"key":"92:1","ar":" وَٱلَّيْلِ إِذَا يَغْشَىٰ","en":"By the night when it covers1","tr":"Wallayli itha yaghsha","juz":30,"page":595},{"s":92,"a":2,"key":"92:2","ar":"وَٱلنَّهَارِ إِذَا تَجَلَّىٰ","en":"And [by] the day when it appears","tr":"Wannahari itha tajalla","juz":30,"page":595},{"s":92,"a":3,"key":"92:3","ar":"وَمَا خَلَقَ ٱلذَّكَرَ وَٱلْأُنثَىٰٓ","en":"And [by] He who created the male and female,","tr":"Wama khalaqa aththakarawal-ontha","juz":30,"page":595},{"s":92,"a":4,"key":"92:4","ar":"إِنَّ سَعْيَكُمْ لَشَتَّىٰ","en":"Indeed, your efforts are diverse.","tr":"Inna saAAyakum lashatta","juz":30,"page":595},{"s":92,"a":5,"key":"92:5","ar":"فَأَمَّا مَنْ أَعْطَىٰ وَٱتَّقَىٰ","en":"As for he who gives and fears Allāh","tr":"Faamma man aAAta wattaqa","juz":30,"page":595},{"s":92,"a":6,"key":"92:6","ar":"وَصَدَّقَ بِٱلْحُسْنَىٰ","en":"And believes in the best [reward],","tr":"Wasaddaqa bilhusna","juz":30,"page":595},{"s":92,"a":7,"key":"92:7","ar":"فَسَنُيَسِّرُهُۥ لِلْيُسْرَىٰ","en":"We will ease him toward ease.","tr":"Fasanuyassiruhu lilyusra","juz":30,"page":595},{"s":92,"a":8,"key":"92:8","ar":"وَأَمَّا مَنۢ بَخِلَ وَٱسْتَغْنَىٰ","en":"But as for he who withholds and considers himself free of need","tr":"Waamma man bakhila wastaghna","juz":30,"page":595},{"s":92,"a":9,"key":"92:9","ar":"وَكَذَّبَ بِٱلْحُسْنَىٰ","en":"And denies the best [reward],","tr":"Wakaththaba bilhusna","juz":30,"page":595},{"s":92,"a":10,"key":"92:10","ar":"فَسَنُيَسِّرُهُۥ لِلْعُسْرَىٰ","en":"We will ease him toward difficulty.","tr":"Fasanuyassiruhu lilAAusra","juz":30,"page":595},{"s":92,"a":11,"key":"92:11","ar":"وَمَا يُغْنِى عَنْهُ مَالُهُۥٓ إِذَا تَرَدَّىٰٓ","en":"And what will his wealth avail him when he falls?1","tr":"Wama yughnee AAanhu maluhu ithataradda","juz":30,"page":595},{"s":92,"a":12,"key":"92:12","ar":"إِنَّ عَلَيْنَا لَلْهُدَىٰ","en":"Indeed, [incumbent] upon Us is guidance.","tr":"Inna AAalayna lalhuda","juz":30,"page":595},{"s":92,"a":13,"key":"92:13","ar":"وَإِنَّ لَنَا لَلْـَٔاخِرَةَ وَٱلْأُولَىٰ","en":"And indeed, to us belongs the Hereafter and the first [life].","tr":"Wa-inna lana lal-akhirata wal-oola","juz":30,"page":595},{"s":92,"a":14,"key":"92:14","ar":"فَأَنذَرْتُكُمْ نَارًا تَلَظَّىٰ","en":"So I have warned you of a Fire which is blazing.","tr":"Faanthartukum naran talaththa","juz":30,"page":595},{"s":92,"a":15,"key":"92:15","ar":"لَا يَصْلَىٰهَآ إِلَّا ٱلْأَشْقَى","en":"None will [enter to] burn therein except the most wretched one","tr":"La yaslaha illaal-ashqa","juz":30,"page":596},{"s":92,"a":16,"key":"92:16","ar":"ٱلَّذِى كَذَّبَ وَتَوَلَّىٰ","en":"Who had denied and turned away.","tr":"Allathee kaththaba watawalla","juz":30,"page":596},{"s":92,"a":17,"key":"92:17","ar":"وَسَيُجَنَّبُهَا ٱلْأَتْقَى","en":"But the righteous one will avoid it","tr":"Wasayujannabuha al-atqa","juz":30,"page":596},{"s":92,"a":18,"key":"92:18","ar":"ٱلَّذِى يُؤْتِى مَالَهُۥ يَتَزَكَّىٰ","en":"[He] who gives [from] his wealth to purify himself","tr":"Allathee yu/tee malahuyatazakka","juz":30,"page":596},{"s":92,"a":19,"key":"92:19","ar":"وَمَا لِأَحَدٍ عِندَهُۥ مِن نِّعْمَةٍ تُجْزَىٰٓ","en":"And not [giving] for anyone who has [done him] a favor to be rewarded1","tr":"Wama li-ahadin AAindahu minniAAmatin tujza","juz":30,"page":596},{"s":92,"a":20,"key":"92:20","ar":"إِلَّا ٱبْتِغَآءَ وَجْهِ رَبِّهِ ٱلْأَعْلَىٰ","en":"But only seeking the face [i.e., acceptance] of his Lord, Most High.","tr":"Illa ibtighaa wajhi rabbihial-aAAla","juz":30,"page":596},{"s":92,"a":21,"key":"92:21","ar":"وَلَسَوْفَ يَرْضَىٰ","en":"And he is going to be satisfied.","tr":"Walasawfa yarda","juz":30,"page":596},{"s":93,"a":1,"key":"93:1","ar":" وَٱلضُّحَىٰ","en":"By the morning brightness","tr":"Wadduha","juz":30,"page":596},{"s":93,"a":2,"key":"93:2","ar":"وَٱلَّيْلِ إِذَا سَجَىٰ","en":"And [by] the night when it covers with darkness,1","tr":"Wallayli itha saja","juz":30,"page":596},{"s":93,"a":3,"key":"93:3","ar":"مَا وَدَّعَكَ رَبُّكَ وَمَا قَلَىٰ","en":"Your Lord has not taken leave of you, [O Muḥammad], nor has He detested [you].","tr":"Ma waddaAAaka rabbuka wama qala","juz":30,"page":596},{"s":93,"a":4,"key":"93:4","ar":"وَلَلْـَٔاخِرَةُ خَيْرٌ لَّكَ مِنَ ٱلْأُولَىٰ","en":"And the Hereafter is better for you than the first [life].","tr":"Walal-akhiratu khayrun laka minaal-oola","juz":30,"page":596},{"s":93,"a":5,"key":"93:5","ar":"وَلَسَوْفَ يُعْطِيكَ رَبُّكَ فَتَرْضَىٰٓ","en":"And your Lord is going to give you, and you will be satisfied.","tr":"Walasawfa yuAAteeka rabbuka fatarda","juz":30,"page":596},{"s":93,"a":6,"key":"93:6","ar":"أَلَمْ يَجِدْكَ يَتِيمًا فَـَٔاوَىٰ","en":"Did He not find you an orphan and give [you] refuge?","tr":"Alam yajidka yateeman faawa","juz":30,"page":596},{"s":93,"a":7,"key":"93:7","ar":"وَوَجَدَكَ ضَآلًّا فَهَدَىٰ","en":"And He found you lost and guided [you],","tr":"Wawajadaka dallan fahada","juz":30,"page":596},{"s":93,"a":8,"key":"93:8","ar":"وَوَجَدَكَ عَآئِلًا فَأَغْنَىٰ","en":"And He found you poor and made [you] self-sufficient.","tr":"Wawajadaka AAa-ilan faaghna","juz":30,"page":596},{"s":93,"a":9,"key":"93:9","ar":"فَأَمَّا ٱلْيَتِيمَ فَلَا تَقْهَرْ","en":"So as for the orphan, do not oppress [him].","tr":"Faamma alyateema fala taqhar","juz":30,"page":596},{"s":93,"a":10,"key":"93:10","ar":"وَأَمَّا ٱلسَّآئِلَ فَلَا تَنْهَرْ","en":"And as for the petitioner,1 do not repel [him].","tr":"Waamma assa-ila falatanhar","juz":30,"page":596},{"s":93,"a":11,"key":"93:11","ar":"وَأَمَّا بِنِعْمَةِ رَبِّكَ فَحَدِّثْ","en":"But as for the favor of your Lord, report [it].","tr":"Waamma biniAAmati rabbika fahaddith","juz":30,"page":596},{"s":94,"a":1,"key":"94:1","ar":" أَلَمْ نَشْرَحْ لَكَ صَدْرَكَ","en":"Did We not expand for you, [O Muḥammad], your breast?1","tr":"Alam nashrah laka sadrak","juz":30,"page":596},{"s":94,"a":2,"key":"94:2","ar":"وَوَضَعْنَا عَنكَ وِزْرَكَ","en":"And We removed from you your burden1","tr":"WawadaAAna AAanka wizrak","juz":30,"page":596},{"s":94,"a":3,"key":"94:3","ar":"ٱلَّذِىٓ أَنقَضَ ظَهْرَكَ","en":"Which had weighed upon your back","tr":"Allathee anqada thahrak","juz":30,"page":596},{"s":94,"a":4,"key":"94:4","ar":"وَرَفَعْنَا لَكَ ذِكْرَكَ","en":"And raised high for you your repute.","tr":"WarafaAAna laka thikrak","juz":30,"page":596},{"s":94,"a":5,"key":"94:5","ar":"فَإِنَّ مَعَ ٱلْعُسْرِ يُسْرًا","en":"For indeed, with hardship [will be] ease [i.e., relief].","tr":"Fa-inna maAAa alAAusri yusra","juz":30,"page":596},{"s":94,"a":6,"key":"94:6","ar":"إِنَّ مَعَ ٱلْعُسْرِ يُسْرًا","en":"Indeed, with hardship [will be] ease.","tr":"Inna maAAa alAAusri yusra","juz":30,"page":596},{"s":94,"a":7,"key":"94:7","ar":"فَإِذَا فَرَغْتَ فَٱنصَبْ","en":"So when you have finished [your duties], then stand up [for worship].","tr":"Fa-itha faraghta fansab","juz":30,"page":596},{"s":94,"a":8,"key":"94:8","ar":"وَإِلَىٰ رَبِّكَ فَٱرْغَب","en":"And to your Lord direct [your] longing.","tr":"Wa-ila rabbika farghab","juz":30,"page":596},{"s":95,"a":1,"key":"95:1","ar":"وَٱلتِّينِ وَٱلزَّيْتُونِ","en":"By the fig and the olive1","tr":"Watteeni wazzaytoon","juz":30,"page":597},{"s":95,"a":2,"key":"95:2","ar":"وَطُورِ سِينِينَ","en":"And [by] Mount Sinai","tr":"Watoori seeneen","juz":30,"page":597},{"s":95,"a":3,"key":"95:3","ar":"وَهَـٰذَا ٱلْبَلَدِ ٱلْأَمِينِ","en":"And [by] this secure city [i.e., Makkah],","tr":"Wahatha albaladi al-ameen","juz":30,"page":597},{"s":95,"a":4,"key":"95:4","ar":"لَقَدْ خَلَقْنَا ٱلْإِنسَـٰنَ فِىٓ أَحْسَنِ تَقْوِيمٍ","en":"We have certainly created man in the best of stature;1","tr":"Laqad khalaqna al-insana fee ahsanitaqweem","juz":30,"page":597},{"s":95,"a":5,"key":"95:5","ar":"ثُمَّ رَدَدْنَـٰهُ أَسْفَلَ سَـٰفِلِينَ","en":"Then We return him to the lowest of the low,1","tr":"Thumma radadnahu asfala safileen","juz":30,"page":597},{"s":95,"a":6,"key":"95:6","ar":"إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ فَلَهُمْ أَجْرٌ غَيْرُ مَمْنُونٍ","en":"Except for those who believe and do righteous deeds, for they will have a reward uninterrupted.","tr":"Illa allatheena amanoowaAAamiloo assalihati falahum ajrun ghayrumamnoon","juz":30,"page":597},{"s":95,"a":7,"key":"95:7","ar":"فَمَا يُكَذِّبُكَ بَعْدُ بِٱلدِّينِ","en":"So what yet causes you to deny the Recompense?1","tr":"Fama yukaththibuka baAAdu biddeen","juz":30,"page":597},{"s":95,"a":8,"key":"95:8","ar":"أَلَيْسَ ٱللَّهُ بِأَحْكَمِ ٱلْحَـٰكِمِينَ","en":"Is not Allāh the most just of judges?","tr":"Alaysa Allahu bi-ahkami alhakimeen","juz":30,"page":597},{"s":96,"a":1,"key":"96:1","ar":" ٱقْرَأْ بِٱسْمِ رَبِّكَ ٱلَّذِى خَلَقَ","en":"Recite in the name of your Lord who created","tr":"Iqra/ bi-ismi rabbika allathee khalaq","juz":30,"page":597},{"s":96,"a":2,"key":"96:2","ar":"خَلَقَ ٱلْإِنسَـٰنَ مِنْ عَلَقٍ","en":"Created man from a clinging substance.","tr":"Khalaqa al-insana min AAalaq","juz":30,"page":597},{"s":96,"a":3,"key":"96:3","ar":"ٱقْرَأْ وَرَبُّكَ ٱلْأَكْرَمُ","en":"Recite, and your Lord is the most Generous -","tr":"Iqra/ warabbuka al-akram","juz":30,"page":597},{"s":96,"a":4,"key":"96:4","ar":"ٱلَّذِى عَلَّمَ بِٱلْقَلَمِ","en":"Who taught by the pen","tr":"Allathee AAallama bilqalam","juz":30,"page":597},{"s":96,"a":5,"key":"96:5","ar":"عَلَّمَ ٱلْإِنسَـٰنَ مَا لَمْ يَعْلَمْ","en":"Taught man that which he knew not.","tr":"AAallama al-insana ma lamyaAAlam","juz":30,"page":597},{"s":96,"a":6,"key":"96:6","ar":"كَلَّآ إِنَّ ٱلْإِنسَـٰنَ لَيَطْغَىٰٓ","en":"No! [But] indeed, man transgresses","tr":"Kalla inna al-insana layatgha","juz":30,"page":597},{"s":96,"a":7,"key":"96:7","ar":"أَن رَّءَاهُ ٱسْتَغْنَىٰٓ","en":"Because he sees himself self-sufficient.","tr":"An raahu istaghna","juz":30,"page":597},{"s":96,"a":8,"key":"96:8","ar":"إِنَّ إِلَىٰ رَبِّكَ ٱلرُّجْعَىٰٓ","en":"Indeed, to your Lord is the return.","tr":"Inna ila rabbika arrujAAa","juz":30,"page":597},{"s":96,"a":9,"key":"96:9","ar":"أَرَءَيْتَ ٱلَّذِى يَنْهَىٰ","en":"Have you seen the one who forbids","tr":"Araayta allathee yanha","juz":30,"page":597},{"s":96,"a":10,"key":"96:10","ar":"عَبْدًا إِذَا صَلَّىٰٓ","en":"A servant when he prays?","tr":"AAabdan itha salla","juz":30,"page":597},{"s":96,"a":11,"key":"96:11","ar":"أَرَءَيْتَ إِن كَانَ عَلَى ٱلْهُدَىٰٓ","en":"Have you seen if he is upon guidance","tr":"Araayta in kana AAala alhuda","juz":30,"page":597},{"s":96,"a":12,"key":"96:12","ar":"أَوْ أَمَرَ بِٱلتَّقْوَىٰٓ","en":"Or enjoins righteousness?","tr":"Aw amara bittaqwa","juz":30,"page":597},{"s":96,"a":13,"key":"96:13","ar":"أَرَءَيْتَ إِن كَذَّبَ وَتَوَلَّىٰٓ","en":"Have you seen if he denies and turns away -","tr":"Araayta in kaththaba watawalla","juz":30,"page":597},{"s":96,"a":14,"key":"96:14","ar":"أَلَمْ يَعْلَم بِأَنَّ ٱللَّهَ يَرَىٰ","en":"Does he not know that Allāh sees?","tr":"Alam yaAAlam bi-anna Allaha yara","juz":30,"page":597},{"s":96,"a":15,"key":"96:15","ar":"كَلَّا لَئِن لَّمْ يَنتَهِ لَنَسْفَعًۢا بِٱلنَّاصِيَةِ","en":"No! If he does not desist, We will surely drag him by the forelock1","tr":"Kalla la-in lam yantahi lanasfaAAanbinnasiya","juz":30,"page":597},{"s":96,"a":16,"key":"96:16","ar":"نَاصِيَةٍ كَـٰذِبَةٍ خَاطِئَةٍ","en":"A lying, sinning forelock.","tr":"Nasiyatin kathibatin khati-a","juz":30,"page":597},{"s":96,"a":17,"key":"96:17","ar":"فَلْيَدْعُ نَادِيَهُۥ","en":"Then let him call his associates;","tr":"FalyadAAu nadiyah","juz":30,"page":597},{"s":96,"a":18,"key":"96:18","ar":"سَنَدْعُ ٱلزَّبَانِيَةَ","en":"We will call the angels of Hell.1","tr":"SanadAAu azzabaniya","juz":30,"page":597},{"s":96,"a":19,"key":"96:19","ar":"كَلَّا لَا تُطِعْهُ وَٱسْجُدْ وَٱقْتَرِب ۩","en":"No! Do not obey him. But prostrate and draw near [to Allāh].","tr":"Kalla la tutiAAhu wasjudwaqtarib","juz":30,"page":597},{"s":97,"a":1,"key":"97:1","ar":"إِنَّآ أَنزَلْنَـٰهُ فِى لَيْلَةِ ٱلْقَدْرِ","en":"Indeed, We sent it [i.e., the Qur’ān] down during the Night of Decree.","tr":"Inna anzalnahu fee laylatialqadr","juz":30,"page":598},{"s":97,"a":2,"key":"97:2","ar":"وَمَآ أَدْرَىٰكَ مَا لَيْلَةُ ٱلْقَدْرِ","en":"And what can make you know what is the Night of Decree?","tr":"Wama adraka ma laylatualqadr","juz":30,"page":598},{"s":97,"a":3,"key":"97:3","ar":"لَيْلَةُ ٱلْقَدْرِ خَيْرٌ مِّنْ أَلْفِ شَهْرٍ","en":"The Night of Decree is better than a thousand months.","tr":"Laylatu alqadri khayrun min alfi shahr","juz":30,"page":598},{"s":97,"a":4,"key":"97:4","ar":"تَنَزَّلُ ٱلْمَلَـٰٓئِكَةُ وَٱلرُّوحُ فِيهَا بِإِذْنِ رَبِّهِم مِّن كُلِّ أَمْرٍ","en":"The angels and the Spirit [i.e., Gabriel] descend therein by permission of their Lord for every matter.1","tr":"Tanazzalu almala-ikatu warroohufeeha bi-ithni rabbihim min kulli amr","juz":30,"page":598},{"s":97,"a":5,"key":"97:5","ar":"سَلَـٰمٌ هِىَ حَتَّىٰ مَطْلَعِ ٱلْفَجْرِ","en":"Peace it is1 until the emergence of dawn.","tr":"Salamun hiya hatta matlaAAialfajr","juz":30,"page":598},{"s":98,"a":1,"key":"98:1","ar":" لَمْ يَكُنِ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَـٰبِ وَٱلْمُشْرِكِينَ مُنفَكِّينَ حَتَّىٰ تَأْتِيَهُمُ ٱلْبَيِّنَةُ","en":"Those who disbelieved among the People of the Scripture and the polytheists were not to be parted [from misbelief]1 until there came to them clear evidence","tr":"Lam yakuni allatheena kafaroo min ahlialkitabi walmushrikeena munfakkeena hattata/tiyahumu albayyina","juz":30,"page":598},{"s":98,"a":2,"key":"98:2","ar":"رَسُولٌ مِّنَ ٱللَّهِ يَتْلُوا۟ صُحُفًا مُّطَهَّرَةً","en":"A Messenger from Allāh, reciting purified1 scriptures","tr":"Rasoolun mina Allahi yatloo suhufanmutahhara","juz":30,"page":598},{"s":98,"a":3,"key":"98:3","ar":"فِيهَا كُتُبٌ قَيِّمَةٌ","en":"Within which are correct writings [i.e., rulings and laws].","tr":"Feeha kutubun qayyima","juz":30,"page":598},{"s":98,"a":4,"key":"98:4","ar":"وَمَا تَفَرَّقَ ٱلَّذِينَ أُوتُوا۟ ٱلْكِتَـٰبَ إِلَّا مِنۢ بَعْدِ مَا جَآءَتْهُمُ ٱلْبَيِّنَةُ","en":"Nor did those who were given the Scripture become divided1 until after there had come to them clear evidence.","tr":"Wama tafarraqa allatheena ootooalkitaba illa min baAAdi ma jaat-humualbayyina","juz":30,"page":598},{"s":98,"a":5,"key":"98:5","ar":"وَمَآ أُمِرُوٓا۟ إِلَّا لِيَعْبُدُوا۟ ٱللَّهَ مُخْلِصِينَ لَهُ ٱلدِّينَ حُنَفَآءَ وَيُقِيمُوا۟ ٱلصَّلَوٰةَ وَيُؤْتُوا۟ ٱلزَّكَوٰةَ ۚ وَذَٰلِكَ دِينُ ٱلْقَيِّمَةِ","en":"And they were not commanded except to worship Allāh, [being] sincere to Him in religion, inclining to truth, and to establish prayer and to give zakāh. And that is the correct religion.","tr":"Wama omiroo illa liyaAAbudooAllaha mukhliseena lahu addeena hunafaawayuqeemoo assalata wayu/too azzakatawathalika deenu alqayyima","juz":30,"page":598},{"s":98,"a":6,"key":"98:6","ar":"إِنَّ ٱلَّذِينَ كَفَرُوا۟ مِنْ أَهْلِ ٱلْكِتَـٰبِ وَٱلْمُشْرِكِينَ فِى نَارِ جَهَنَّمَ خَـٰلِدِينَ فِيهَآ ۚ أُو۟لَـٰٓئِكَ هُمْ شَرُّ ٱلْبَرِيَّةِ","en":"Indeed, they who disbelieved among the People of the Scripture and the polytheists will be in the fire of Hell, abiding eternally therein. Those are the worst of creatures.","tr":"Inna allatheena kafaroo min ahli alkitabiwalmushrikeena fee nari jahannama khalideenafeeha ola-ika hum sharru albariyya","juz":30,"page":598},{"s":98,"a":7,"key":"98:7","ar":"إِنَّ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ أُو۟لَـٰٓئِكَ هُمْ خَيْرُ ٱلْبَرِيَّةِ","en":"Indeed, they who have believed and done righteous deeds - those are the best of creatures.","tr":"Inna allatheena amanoowaAAamiloo assalihati ola-ika humkhayru albariyya","juz":30,"page":598},{"s":98,"a":8,"key":"98:8","ar":"جَزَآؤُهُمْ عِندَ رَبِّهِمْ جَنَّـٰتُ عَدْنٍ تَجْرِى مِن تَحْتِهَا ٱلْأَنْهَـٰرُ خَـٰلِدِينَ فِيهَآ أَبَدًا ۖ رَّضِىَ ٱللَّهُ عَنْهُمْ وَرَضُوا۟ عَنْهُ ۚ ذَٰلِكَ لِمَنْ خَشِىَ رَبَّهُۥ","en":"Their reward with their Lord will be gardens of perpetual residence beneath which rivers flow, wherein they will abide forever, Allāh being pleased with them and they with Him. That is for whoever has feared his Lord.","tr":"Jazaohum AAinda rabbihim jannatuAAadnin tajree min tahtiha al-anharu khalideenafeeha abadan radiya Allahu AAanhum waradooAAanhu thalika liman khashiya rabbah","juz":30,"page":599},{"s":99,"a":1,"key":"99:1","ar":" إِذَا زُلْزِلَتِ ٱلْأَرْضُ زِلْزَالَهَا","en":"When the earth is shaken with its [final] earthquake","tr":"Itha zulzilati al-ardu zilzalaha","juz":30,"page":599},{"s":99,"a":2,"key":"99:2","ar":"وَأَخْرَجَتِ ٱلْأَرْضُ أَثْقَالَهَا","en":"And the earth discharges its burdens1","tr":"Waakhrajati al-ardu athqalaha","juz":30,"page":599},{"s":99,"a":3,"key":"99:3","ar":"وَقَالَ ٱلْإِنسَـٰنُ مَا لَهَا","en":"And man says,1 \"What is [wrong] with it?\" -","tr":"Waqala al-insanu ma laha","juz":30,"page":599},{"s":99,"a":4,"key":"99:4","ar":"يَوْمَئِذٍ تُحَدِّثُ أَخْبَارَهَا","en":"That Day, it will report its news","tr":"Yawma-ithin tuhaddithu akhbaraha","juz":30,"page":599},{"s":99,"a":5,"key":"99:5","ar":"بِأَنَّ رَبَّكَ أَوْحَىٰ لَهَا","en":"Because your Lord has inspired [i.e., commanded] it.","tr":"Bi-anna rabbaka awha laha","juz":30,"page":599},{"s":99,"a":6,"key":"99:6","ar":"يَوْمَئِذٍ يَصْدُرُ ٱلنَّاسُ أَشْتَاتًا لِّيُرَوْا۟ أَعْمَـٰلَهُمْ","en":"That Day, the people will depart1 separated [into categories] to be shown [the result of] their deeds.","tr":"Yawma-ithin yasduru annasuashtatan liyuraw aAAmalahum","juz":30,"page":599},{"s":99,"a":7,"key":"99:7","ar":"فَمَن يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُۥ","en":"So whoever does an atom's weight1 of good will see it,","tr":"Faman yaAAmal mithqala tharratinkhayran yarah","juz":30,"page":599},{"s":99,"a":8,"key":"99:8","ar":"وَمَن يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُۥ","en":"And whoever does an atom's weight of evil will see it.","tr":"Waman yaAAmal mithqala tharratinsharran yarah","juz":30,"page":599},{"s":100,"a":1,"key":"100:1","ar":" وَٱلْعَـٰدِيَـٰتِ ضَبْحًا","en":"By the racers, panting,1","tr":"WalAAadiyati dabha","juz":30,"page":599},{"s":100,"a":2,"key":"100:2","ar":"فَٱلْمُورِيَـٰتِ قَدْحًا","en":"And the producers of sparks [when] striking1","tr":"Falmooriyati qadha","juz":30,"page":599},{"s":100,"a":3,"key":"100:3","ar":"فَٱلْمُغِيرَٰتِ صُبْحًا","en":"And the chargers at dawn,1","tr":"Falmugheerati subha","juz":30,"page":599},{"s":100,"a":4,"key":"100:4","ar":"فَأَثَرْنَ بِهِۦ نَقْعًا","en":"Stirring up thereby [clouds of] dust,","tr":"Faatharna bihi naqAAa","juz":30,"page":599},{"s":100,"a":5,"key":"100:5","ar":"فَوَسَطْنَ بِهِۦ جَمْعًا","en":"Arriving thereby in the center1 collectively,","tr":"Fawasatna bihi jamAAa","juz":30,"page":599},{"s":100,"a":6,"key":"100:6","ar":"إِنَّ ٱلْإِنسَـٰنَ لِرَبِّهِۦ لَكَنُودٌ","en":"Indeed mankind, to his Lord, is ungrateful.","tr":"Inna al-insana lirabbihi lakanood","juz":30,"page":599},{"s":100,"a":7,"key":"100:7","ar":"وَإِنَّهُۥ عَلَىٰ ذَٰلِكَ لَشَهِيدٌ","en":"And indeed, he is to that a witness.1","tr":"Wa-innahu AAala thalikalashaheed","juz":30,"page":599},{"s":100,"a":8,"key":"100:8","ar":"وَإِنَّهُۥ لِحُبِّ ٱلْخَيْرِ لَشَدِيدٌ","en":"And indeed he is, in love of wealth, intense.","tr":"Wa-innahu lihubbi alkhayri lashadeed","juz":30,"page":599},{"s":100,"a":9,"key":"100:9","ar":"۞ أَفَلَا يَعْلَمُ إِذَا بُعْثِرَ مَا فِى ٱلْقُبُورِ","en":"But does he not know that when the contents of the graves are scattered","tr":"Afala yaAAlamu itha buAAthira mafee alquboor","juz":30,"page":599},{"s":100,"a":10,"key":"100:10","ar":"وَحُصِّلَ مَا فِى ٱلصُّدُورِ","en":"And that within the breasts is obtained,1","tr":"Wahussila ma fee assudoor","juz":30,"page":600},{"s":100,"a":11,"key":"100:11","ar":"إِنَّ رَبَّهُم بِهِمْ يَوْمَئِذٍ لَّخَبِيرٌۢ","en":"Indeed, their Lord with them, that Day, is [fully] Aware.1","tr":"Inna rabbahum bihim yawma-ithinlakhabeer","juz":30,"page":600},{"s":101,"a":1,"key":"101:1","ar":" ٱلْقَارِعَةُ","en":"The Striking Calamity -","tr":"AlqariAAa","juz":30,"page":600},{"s":101,"a":2,"key":"101:2","ar":"مَا ٱلْقَارِعَةُ","en":"What is the Striking Calamity?","tr":"Ma alqariAAa","juz":30,"page":600},{"s":101,"a":3,"key":"101:3","ar":"وَمَآ أَدْرَىٰكَ مَا ٱلْقَارِعَةُ","en":"And what can make you know what is the Striking Calamity?","tr":"Wama adraka ma alqariAAa","juz":30,"page":600},{"s":101,"a":4,"key":"101:4","ar":"يَوْمَ يَكُونُ ٱلنَّاسُ كَٱلْفَرَاشِ ٱلْمَبْثُوثِ","en":"It is the Day when people will be like moths, dispersed,1","tr":"Yawma yakoonu annasu kalfarashialmabthooth","juz":30,"page":600},{"s":101,"a":5,"key":"101:5","ar":"وَتَكُونُ ٱلْجِبَالُ كَٱلْعِهْنِ ٱلْمَنفُوشِ","en":"And the mountains will be like wool, fluffed up.1","tr":"Watakoonu aljibalu kalAAihnialmanfoosh","juz":30,"page":600},{"s":101,"a":6,"key":"101:6","ar":"فَأَمَّا مَن ثَقُلَتْ مَوَٰزِينُهُۥ","en":"Then as for one whose scales are heavy [with good deeds],","tr":"Faamma man thaqulat mawazeenuh","juz":30,"page":600},{"s":101,"a":7,"key":"101:7","ar":"فَهُوَ فِى عِيشَةٍ رَّاضِيَةٍ","en":"He will be in a pleasant life.","tr":"Fahuwa fee AAeeshatin radiya","juz":30,"page":600},{"s":101,"a":8,"key":"101:8","ar":"وَأَمَّا مَنْ خَفَّتْ مَوَٰزِينُهُۥ","en":"But as for one whose scales are light,","tr":"Waamma man khaffat mawazeenuh","juz":30,"page":600},{"s":101,"a":9,"key":"101:9","ar":"فَأُمُّهُۥ هَاوِيَةٌ","en":"His refuge1 will be an abyss.2","tr":"Faommuhu hawiya","juz":30,"page":600},{"s":101,"a":10,"key":"101:10","ar":"وَمَآ أَدْرَىٰكَ مَا هِيَهْ","en":"And what can make you know what that is?","tr":"Wama adraka ma hiya","juz":30,"page":600},{"s":101,"a":11,"key":"101:11","ar":"نَارٌ حَامِيَةٌۢ","en":"It is a Fire, intensely hot.","tr":"Narun hamiya","juz":30,"page":600},{"s":102,"a":1,"key":"102:1","ar":" أَلْهَىٰكُمُ ٱلتَّكَاثُرُ","en":"Competition in [worldly] increase diverts you","tr":"Alhakumu attakathur","juz":30,"page":600},{"s":102,"a":2,"key":"102:2","ar":"حَتَّىٰ زُرْتُمُ ٱلْمَقَابِرَ","en":"Until you visit the graveyards.1","tr":"Hatta zurtumu almaqabir","juz":30,"page":600},{"s":102,"a":3,"key":"102:3","ar":"كَلَّا سَوْفَ تَعْلَمُونَ","en":"No! You are going to know.","tr":"Kalla sawfa taAAlamoon","juz":30,"page":600},{"s":102,"a":4,"key":"102:4","ar":"ثُمَّ كَلَّا سَوْفَ تَعْلَمُونَ","en":"Then, no! You are going to know.","tr":"Thumma kalla sawfa taAAlamoon","juz":30,"page":600},{"s":102,"a":5,"key":"102:5","ar":"كَلَّا لَوْ تَعْلَمُونَ عِلْمَ ٱلْيَقِينِ","en":"No! If you only knew with knowledge of certainty...1","tr":"Kalla law taAAlamoona AAilma alyaqeen","juz":30,"page":600},{"s":102,"a":6,"key":"102:6","ar":"لَتَرَوُنَّ ٱلْجَحِيمَ","en":"You will surely see the Hellfire.","tr":"Latarawunna aljaheem","juz":30,"page":600},{"s":102,"a":7,"key":"102:7","ar":"ثُمَّ لَتَرَوُنَّهَا عَيْنَ ٱلْيَقِينِ","en":"Then you will surely see it with the eye of certainty.1","tr":"Thumma latarawunnaha AAayna alyaqeen","juz":30,"page":600},{"s":102,"a":8,"key":"102:8","ar":"ثُمَّ لَتُسْـَٔلُنَّ يَوْمَئِذٍ عَنِ ٱلنَّعِيمِ","en":"Then you will surely be asked that Day about pleasure.1","tr":"Thumma latus-alunna yawma-ithin AAaniannaAAeem","juz":30,"page":600},{"s":103,"a":1,"key":"103:1","ar":" وَٱلْعَصْرِ","en":"By time,1","tr":"WalAAasr","juz":30,"page":601},{"s":103,"a":2,"key":"103:2","ar":"إِنَّ ٱلْإِنسَـٰنَ لَفِى خُسْرٍ","en":"Indeed, mankind is in loss,","tr":"Inna al-insana lafee khusr","juz":30,"page":601},{"s":103,"a":3,"key":"103:3","ar":"إِلَّا ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّـٰلِحَـٰتِ وَتَوَاصَوْا۟ بِٱلْحَقِّ وَتَوَاصَوْا۟ بِٱلصَّبْرِ","en":"Except for those who have believed and done righteous deeds and advised each other to truth and advised each other to patience.","tr":"Illa allatheena amanoowaAAamiloo assalihati watawasaw bilhaqqiwatawasaw bissabr","juz":30,"page":601},{"s":104,"a":1,"key":"104:1","ar":" وَيْلٌ لِّكُلِّ هُمَزَةٍ لُّمَزَةٍ","en":"Woe to every scorner and mocker","tr":"Waylun likulli humazatin lumaza","juz":30,"page":601},{"s":104,"a":2,"key":"104:2","ar":"ٱلَّذِى جَمَعَ مَالًا وَعَدَّدَهُۥ","en":"Who collects wealth and [continuously] counts it.1","tr":"Allathee jamaAAa malanwaAAaddadah","juz":30,"page":601},{"s":104,"a":3,"key":"104:3","ar":"يَحْسَبُ أَنَّ مَالَهُۥٓ أَخْلَدَهُۥ","en":"He thinks that his wealth will make him immortal.","tr":"Yahsabu anna malahu akhladah","juz":30,"page":601},{"s":104,"a":4,"key":"104:4","ar":"كَلَّا ۖ لَيُنۢبَذَنَّ فِى ٱلْحُطَمَةِ","en":"No! He will surely be thrown into the Crusher.1","tr":"Kalla layunbathanna fee alhutama","juz":30,"page":601},{"s":104,"a":5,"key":"104:5","ar":"وَمَآ أَدْرَىٰكَ مَا ٱلْحُطَمَةُ","en":"And what can make you know what is the Crusher?","tr":"Wama adraka ma alhutama","juz":30,"page":601},{"s":104,"a":6,"key":"104:6","ar":"نَارُ ٱللَّهِ ٱلْمُوقَدَةُ","en":"It is the fire of Allāh, [eternally] fueled,","tr":"Naru Allahi almooqada","juz":30,"page":601},{"s":104,"a":7,"key":"104:7","ar":"ٱلَّتِى تَطَّلِعُ عَلَى ٱلْأَفْـِٔدَةِ","en":"Which mounts directed at the hearts.1","tr":"Allatee tattaliAAu AAalaal-af-ida","juz":30,"page":601},{"s":104,"a":8,"key":"104:8","ar":"إِنَّهَا عَلَيْهِم مُّؤْصَدَةٌ","en":"Indeed, it [i.e., Hellfire] will be closed down upon them","tr":"lnnaha AAalayhim mu/sada","juz":30,"page":601},{"s":104,"a":9,"key":"104:9","ar":"فِى عَمَدٍ مُّمَدَّدَةٍۭ","en":"In extended columns.1","tr":"Fee AAamadin mumaddada","juz":30,"page":601},{"s":105,"a":1,"key":"105:1","ar":" أَلَمْ تَرَ كَيْفَ فَعَلَ رَبُّكَ بِأَصْحَـٰبِ ٱلْفِيلِ","en":"Have you not considered, [O Muḥammad], how your Lord dealt with the companions of the elephant?1","tr":"Alam tara kayfa faAAala rabbuka bi-as-habialfeel","juz":30,"page":601},{"s":105,"a":2,"key":"105:2","ar":"أَلَمْ يَجْعَلْ كَيْدَهُمْ فِى تَضْلِيلٍ","en":"Did He not make their plan into misguidance?1","tr":"Alam yajAAal kaydahum fee tadleel","juz":30,"page":601},{"s":105,"a":3,"key":"105:3","ar":"وَأَرْسَلَ عَلَيْهِمْ طَيْرًا أَبَابِيلَ","en":"And He sent against them birds in flocks,","tr":"Waarsala AAalayhim tayran ababeel","juz":30,"page":601},{"s":105,"a":4,"key":"105:4","ar":"تَرْمِيهِم بِحِجَارَةٍ مِّن سِجِّيلٍ","en":"Striking them with stones of hard clay,","tr":"Tarmeehim bihijaratin minsijjeel","juz":30,"page":601},{"s":105,"a":5,"key":"105:5","ar":"فَجَعَلَهُمْ كَعَصْفٍ مَّأْكُولٍۭ","en":"And He made them like eaten straw.1","tr":"FajaAAalahum kaAAasfin ma/kool","juz":30,"page":601},{"s":106,"a":1,"key":"106:1","ar":" لِإِيلَـٰفِ قُرَيْشٍ","en":"For the accustomed security of the Quraysh1 -","tr":"Li-eelafi quraysh","juz":30,"page":602},{"s":106,"a":2,"key":"106:2","ar":"إِۦلَـٰفِهِمْ رِحْلَةَ ٱلشِّتَآءِ وَٱلصَّيْفِ","en":"Their accustomed security [in] the caravan of winter and summer1 -","tr":"Eelafihim rihlata ashshita-iwassayf","juz":30,"page":602},{"s":106,"a":3,"key":"106:3","ar":"فَلْيَعْبُدُوا۟ رَبَّ هَـٰذَا ٱلْبَيْتِ","en":"Let them worship the Lord of this House,1","tr":"FalyaAAbudoo rabba hatha albayt","juz":30,"page":602},{"s":106,"a":4,"key":"106:4","ar":"ٱلَّذِىٓ أَطْعَمَهُم مِّن جُوعٍ وَءَامَنَهُم مِّنْ خَوْفٍۭ","en":"Who has fed them, [saving them] from hunger and made them safe, [saving them] from fear.","tr":"Allathee atAAamahum min jooAAinwaamanahum min khawf","juz":30,"page":602},{"s":107,"a":1,"key":"107:1","ar":" أَرَءَيْتَ ٱلَّذِى يُكَذِّبُ بِٱلدِّينِ","en":"Have you seen the one who denies the Recompense?","tr":"Araayta allathee yukaththibu biddeen","juz":30,"page":602},{"s":107,"a":2,"key":"107:2","ar":"فَذَٰلِكَ ٱلَّذِى يَدُعُّ ٱلْيَتِيمَ","en":"For that is the one who drives away the orphan","tr":"Fathalika allathee yaduAAAAualyateem","juz":30,"page":602},{"s":107,"a":3,"key":"107:3","ar":"وَلَا يَحُضُّ عَلَىٰ طَعَامِ ٱلْمِسْكِينِ","en":"And does not encourage the feeding of the poor.","tr":"Wala yahuddu AAalataAAami almiskeen","juz":30,"page":602},{"s":107,"a":4,"key":"107:4","ar":"فَوَيْلٌ لِّلْمُصَلِّينَ","en":"So woe to those who pray","tr":"Fawaylun lilmusalleen","juz":30,"page":602},{"s":107,"a":5,"key":"107:5","ar":"ٱلَّذِينَ هُمْ عَن صَلَاتِهِمْ سَاهُونَ","en":"[But] who are heedless of their prayer1 -","tr":"Allatheena hum AAan salatihimsahoon","juz":30,"page":602},{"s":107,"a":6,"key":"107:6","ar":"ٱلَّذِينَ هُمْ يُرَآءُونَ","en":"Those who make show [of their deeds]","tr":"Allatheena hum yuraoon","juz":30,"page":602},{"s":107,"a":7,"key":"107:7","ar":"وَيَمْنَعُونَ ٱلْمَاعُونَ","en":"And withhold [simple] assistance.","tr":"WayamnaAAoona almaAAoon","juz":30,"page":602},{"s":108,"a":1,"key":"108:1","ar":" إِنَّآ أَعْطَيْنَـٰكَ ٱلْكَوْثَرَ","en":"Indeed, We have granted you, [O Muḥammad], al-Kawthar.","tr":"Inna aAAtaynakaalkawthar","juz":30,"page":602},{"s":108,"a":2,"key":"108:2","ar":"فَصَلِّ لِرَبِّكَ وَٱنْحَرْ","en":"So pray to your Lord and offer sacrifice [to Him alone].","tr":"Fasalli lirabbika wanhar","juz":30,"page":602},{"s":108,"a":3,"key":"108:3","ar":"إِنَّ شَانِئَكَ هُوَ ٱلْأَبْتَرُ","en":"Indeed, your enemy is the one cut off.1","tr":"Inna shani-aka huwa al-abtar","juz":30,"page":602},{"s":109,"a":1,"key":"109:1","ar":" قُلْ يَـٰٓأَيُّهَا ٱلْكَـٰفِرُونَ","en":"Say, \"O disbelievers,","tr":"Qul ya ayyuha alkafiroon","juz":30,"page":603},{"s":109,"a":2,"key":"109:2","ar":"لَآ أَعْبُدُ مَا تَعْبُدُونَ","en":"I do not worship what you worship.","tr":"La aAAbudu ma taAAbudoon","juz":30,"page":603},{"s":109,"a":3,"key":"109:3","ar":"وَلَآ أَنتُمْ عَـٰبِدُونَ مَآ أَعْبُدُ","en":"Nor are you worshippers of what I worship.","tr":"Wala antum AAabidoona maaAAbud","juz":30,"page":603},{"s":109,"a":4,"key":"109:4","ar":"وَلَآ أَنَا۠ عَابِدٌ مَّا عَبَدتُّمْ","en":"Nor will I be a worshipper of what you worship.","tr":"Wala ana AAabidun maAAabadtum","juz":30,"page":603},{"s":109,"a":5,"key":"109:5","ar":"وَلَآ أَنتُمْ عَـٰبِدُونَ مَآ أَعْبُدُ","en":"Nor will you be worshippers of what I worship.","tr":"Wala antum AAabidoona maaAAbud","juz":30,"page":603},{"s":109,"a":6,"key":"109:6","ar":"لَكُمْ دِينُكُمْ وَلِىَ دِينِ","en":"For you is your religion, and for me is my religion.\"","tr":"Lakum deenukum waliya deen","juz":30,"page":603},{"s":110,"a":1,"key":"110:1","ar":" إِذَا جَآءَ نَصْرُ ٱللَّهِ وَٱلْفَتْحُ","en":"When the victory of Allāh has come and the conquest,1","tr":"Itha jaa nasru Allahiwalfath","juz":30,"page":603},{"s":110,"a":2,"key":"110:2","ar":"وَرَأَيْتَ ٱلنَّاسَ يَدْخُلُونَ فِى دِينِ ٱللَّهِ أَفْوَاجًا","en":"And you see the people entering into the religion of Allāh in multitudes,","tr":"Waraayta annasa yadkhuloonafee deeni Allahi afwaja","juz":30,"page":603},{"s":110,"a":3,"key":"110:3","ar":"فَسَبِّحْ بِحَمْدِ رَبِّكَ وَٱسْتَغْفِرْهُ ۚ إِنَّهُۥ كَانَ تَوَّابًۢا","en":"Then exalt [Him] with praise of your Lord and ask forgiveness of Him. Indeed, He is ever Accepting of Repentance.1","tr":"Fasabbih bihamdi rabbika wastaghfirhuinnahu kana tawwaba","juz":30,"page":603},{"s":111,"a":1,"key":"111:1","ar":" تَبَّتْ يَدَآ أَبِى لَهَبٍ وَتَبَّ","en":"May the hands of Abū Lahab be ruined, and ruined is he.1","tr":"Tabbat yada abee lahabin watab","juz":30,"page":603},{"s":111,"a":2,"key":"111:2","ar":"مَآ أَغْنَىٰ عَنْهُ مَالُهُۥ وَمَا كَسَبَ","en":"His wealth will not avail him or that which he gained.","tr":"Ma aghna AAanhu maluhuwama kasab","juz":30,"page":603},{"s":111,"a":3,"key":"111:3","ar":"سَيَصْلَىٰ نَارًا ذَاتَ لَهَبٍ","en":"He will [enter to] burn in a Fire of [blazing] flame","tr":"Sayasla naran thatalahab","juz":30,"page":603},{"s":111,"a":4,"key":"111:4","ar":"وَٱمْرَأَتُهُۥ حَمَّالَةَ ٱلْحَطَبِ","en":"And his wife [as well] - the carrier of firewood.1","tr":"Wamraatuhu hammalata alhatab","juz":30,"page":603},{"s":111,"a":5,"key":"111:5","ar":"فِى جِيدِهَا حَبْلٌ مِّن مَّسَدٍۭ","en":"Around her neck is a rope of [twisted] fiber.","tr":"Fee jeediha hablun min masad","juz":30,"page":603},{"s":112,"a":1,"key":"112:1","ar":" قُلْ هُوَ ٱللَّهُ أَحَدٌ","en":"Say, \"He is Allāh, [who is] One,1","tr":"Qul huwa Allahu ahad","juz":30,"page":604},{"s":112,"a":2,"key":"112:2","ar":"ٱللَّهُ ٱلصَّمَدُ","en":"Allāh, the Eternal Refuge.1","tr":"Allahu assamad","juz":30,"page":604},{"s":112,"a":3,"key":"112:3","ar":"لَمْ يَلِدْ وَلَمْ يُولَدْ","en":"He neither begets nor is born,","tr":"Lam yalid walam yoolad","juz":30,"page":604},{"s":112,"a":4,"key":"112:4","ar":"وَلَمْ يَكُن لَّهُۥ كُفُوًا أَحَدٌۢ","en":"Nor is there to Him any equivalent.\"","tr":"Walam yakun lahu kufuwan ahad","juz":30,"page":604},{"s":113,"a":1,"key":"113:1","ar":" قُلْ أَعُوذُ بِرَبِّ ٱلْفَلَقِ","en":"Say, \"I seek refuge in the Lord of daybreak","tr":"Qul aAAoothu birabbi alfalaq","juz":30,"page":604},{"s":113,"a":2,"key":"113:2","ar":"مِن شَرِّ مَا خَلَقَ","en":"From the evil of that which He created","tr":"Min sharri ma khalaq","juz":30,"page":604},{"s":113,"a":3,"key":"113:3","ar":"وَمِن شَرِّ غَاسِقٍ إِذَا وَقَبَ","en":"And from the evil of darkness when it settles","tr":"Wamin sharri ghasiqin ithawaqab","juz":30,"page":604},{"s":113,"a":4,"key":"113:4","ar":"وَمِن شَرِّ ٱلنَّفَّـٰثَـٰتِ فِى ٱلْعُقَدِ","en":"And from the evil of the blowers in knots1","tr":"Wamin sharri annaffathatifee alAAuqad","juz":30,"page":604},{"s":113,"a":5,"key":"113:5","ar":"وَمِن شَرِّ حَاسِدٍ إِذَا حَسَدَ","en":"And from the evil of an envier when he envies.\"","tr":"Wamin sharri hasidin itha hasad","juz":30,"page":604},{"s":114,"a":1,"key":"114:1","ar":" قُلْ أَعُوذُ بِرَبِّ ٱلنَّاسِ","en":"Say, \"I seek refuge in the Lord of mankind,","tr":"Qul aAAoothu birabbi annas","juz":30,"page":604},{"s":114,"a":2,"key":"114:2","ar":"مَلِكِ ٱلنَّاسِ","en":"The Sovereign of mankind,","tr":"Maliki annas","juz":30,"page":604},{"s":114,"a":3,"key":"114:3","ar":"إِلَـٰهِ ٱلنَّاسِ","en":"The God of mankind,","tr":"Ilahi annas","juz":30,"page":604},{"s":114,"a":4,"key":"114:4","ar":"مِن شَرِّ ٱلْوَسْوَاسِ ٱلْخَنَّاسِ","en":"From the evil of the retreating whisperer1 -","tr":"Min sharri alwaswasi alkhannas","juz":30,"page":604},{"s":114,"a":5,"key":"114:5","ar":"ٱلَّذِى يُوَسْوِسُ فِى صُدُورِ ٱلنَّاسِ","en":"Who whispers [evil] into the breasts of mankind -","tr":"Allathee yuwaswisu fee sudoori annas","juz":30,"page":604},{"s":114,"a":6,"key":"114:6","ar":"مِنَ ٱلْجِنَّةِ وَٱلنَّاسِ","en":"From among the jinn and mankind\".1","tr":"Mina aljinnati wannas","juz":30,"page":604}];
